/* LinguiVance — kelimeler.js */
const KELIMELER = [{"w":"about","tr":"hakkında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Concerning or approximately","dt":"İlgili veya yaklaşık","e1":"Tell me about your day.","e1t":"Bana günün hakkında bir şeyler anlat.","e2":"It is about 5 o'clock.","e2t":"Saat yaklaşık 5."},{"w":"above","tr":"yukarıda","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"In a higher place or position","dt":"Daha yüksek bir yerde veya konumda","e1":"The sun is above the clouds.","e1t":"Güneş bulutların yukarısında.","e2":"Read the sentence above.","e2t":"Yukarıdaki cümleyi oku."},{"w":"acorn","tr":"meşe palamudu","te":"Noun","tt":"İsim","de":"The nut of an oak tree","dt":"Meşe ağacının meyvesi","e1":"The squirrel is eating an acorn.","e1t":"Sincap bir meşe palamudu yiyor.","e2":"Small acorn.","e2t":"Küçük meşe palamudu."},{"w":"across","tr":"karşısında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"From one side to the other","dt":"Bir taraftan diğerine","e1":"The pharmacy is across the street.","e1t":"Eczane sokağın karşısında.","e2":"He ran across the road.","e2t":"Yolun karşısına (bir ucundan diğerine) koştu."},{"w":"actor","tr":"aktör / oyuncu","te":"Noun","tt":"İsim","de":"A person who acts in a movie or play","dt":"Film veya oyunda oynayan kişi","e1":"He is a famous actor.","e1t":"O ünlü bir aktördür.","e2":"Cinema actor.","e2t":"Sinema oyuncusu."},{"w":"address","tr":"adres","te":"Noun","tt":"İsim","de":"The details of where a building is","dt":"Bir binanın nerede olduğuna dair detaylar","e1":"What is your home address?","e1t":"Ev adresin ne?","e2":"Write your address here.","e2t":"Adresini buraya yaz."},{"w":"again","tr":"tekrar","te":"Adverb","tt":"Zarf","de":"One more time","dt":"Bir kez daha","e1":"Can you say that again?","e1t":"Onu tekrar söyleyebilir misin?","e2":"I want to see this movie again.","e2t":"Bu filmi tekrar izlemek istiyorum."},{"w":"air","tr":"hava","te":"Noun","tt":"İsim","de":"The mixture of gases that we breathe","dt":"Nefes aldığımız gaz karışımı","e1":"The mountain air is fresh.","e1t":"Dağ havası taze.","e2":"I need some fresh air.","e2t":"Biraz taze havaya ihtiyacım var."},{"w":"airplane","tr":"uçak","te":"Noun","tt":"İsim","de":"A vehicle that flies and has wings","dt":"Kanatları olan ve uçan taşıt","e1":"The airplane is in the sky.","e1t":"Uçak gökyüzünde.","e2":"I am afraid of flying in an airplane.","e2t":"Uçakla uçmaktan korkarım."},{"w":"airport","tr":"havaalanı","te":"Noun","tt":"İsim","de":"A place where airplanes land and take off","dt":"Uçakların indiği ve kalktığı yer","e1":"The airport is far from the city.","e1t":"Havaalanı şehirden uzak.","e2":"We need to be at the airport early.","e2t":"Havaalanında erken olmamız gerekiyor."},{"w":"all","tr":"hepsi","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"The whole number or amount of","dt":"Sayının veya miktarın tamamı","e1":"All the students are here.","e1t":"Tüm öğrenciler burada.","e2":"Is that all?","e2t":"Hepsi bu mu?"},{"w":"almost","tr":"neredeyse","te":"Adverb","tt":"Zarf","de":"Not quite; very nearly","dt":"Tam değil; çok yakın","e1":"I am almost ready.","e1t":"Neredeyse hazırım.","e2":"It is almost midnight.","e2t":"Neredeyse gece yarısı."},{"w":"already","tr":"zaten / çoktan","te":"Adverb","tt":"Zarf","de":"Before now or before a particular time","dt":"Şimdiden veya belirli bir zamandan önce","e1":"I have already finished my work.","e1t":"İşimi çoktan bitirdim.","e2":"Is it 8 o'clock already?","e2t":"Saat çoktan 8 oldu mu?"},{"w":"always","tr":"her zaman","te":"Adverb","tt":"Zarf","de":"At all times","dt":"Her vakit","e1":"I always wake up early.","e1t":"Her zaman erken uyanırım.","e2":"She always speaks the truth.","e2t":"O her zaman doğruyu söyler."},{"w":"anchor","tr":"çapa / demir","te":"Noun/Verb","tt":"İsim/Fiil","de":"A heavy metal object to hold a boat","dt":"Tekneyi sabitlemek için ağır metal nesne","e1":"Drop the anchor here.","e1t":"Çapayı buraya at.","e2":"The boat is at anchor.","e2t":"Tekne demirlemiş durumda."},{"w":"and","tr":"ve","te":"Conjunction","tt":"Bağlaç","de":"Used to connect words or sentences","dt":"Kelimeleri veya cümleleri bağlamak için kullanılır","e1":"I like tea and coffee.","e1t":"Çay ve kahveyi severim.","e2":"He stood up and left.","e2t":"Ayağa kalktı ve gitti."},{"w":"angry","tr":"kızgın","te":"Adjective","tt":"Sıfat","de":"Feeling or showing strong annoyance or displeasure","dt":"Güçlü bir rahatsızlık veya memnuniyetsizlik hissetme","e1":"My father is angry with me.","e1t":"Babam bana kızgın.","e2":"Don't make him angry.","e2t":"Onu kızdırma."},{"w":"animal","tr":"hayvan","te":"Noun","tt":"İsim","de":"A living creature that is not a human or plant","dt":"İnsan veya bitki olmayan canlı yaratık","e1":"I love all kinds of animals.","e1t":"Her tür hayvanı severim.","e2":"A lion is a wild animal.","e2t":"Aslan vahşi bir hayvandır."},{"w":"another","tr":"başka, bir diğeri","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"One more; a different one","dt":"Bir tane daha; farklı bir tane","e1":"Can I have another cup of tea?","e1t":"Bir fincan daha çay alabilir miyim?","e2":"Show me another color.","e2t":"Bana başka bir renk göster."},{"w":"answer","tr":"cevap","te":"Noun","tt":"İsim","de":"A reaction to a question or situation","dt":"Bir soruya veya duruma verilen tepki","e1":"I don't know the answer.","e1t":"Cevabı bilmiyorum.","e2":"Please give me an answer.","e2t":"Lütfen bana bir cevap ver."},{"w":"any","tr":"herhangi","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"Used in negative and interrogative sentences","dt":"Olumsuz ve soru cümlelerinde kullanılır","e1":"Do you have any questions?","e1t":"Hiç (herhangi bir) sorunuz var mı?","e2":"I don't have any money.","e2t":"Hiç param yok."},{"w":"apple","tr":"elma","te":"Noun","tt":"İsim","de":"A round fruit with red or green skin","dt":"Kırmızı veya yeşil kabuklu yuvarlak bir meyve","e1":"I eat an apple every day.","e1t":"Her gün bir elma yerim.","e2":"This apple is very sweet.","e2t":"Bu elma çok tatlı."},{"w":"april","tr":"Nisan","te":"Noun","tt":"İsim","de":"The fourth month of the year","dt":"Yılın dördüncü ayı","e1":"Flowers bloom in April.","e1t":"Çiçekler Nisanda açar.","e2":"April is a beautiful month.","e2t":"Nisan güzel bir aydır."},{"w":"arm","tr":"kol","te":"Noun","tt":"İsim","de":"The part of the body between the shoulder and hand","dt":"Omuz ile el arasındaki vücut bölümü","e1":"He broke his arm.","e1t":"Kolunu kırdı.","e2":"She is holding a baby in her arms.","e2t":"Kollarında bir bebek tutuyor."},{"w":"around","tr":"etrafında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"On every side of; surrounding","dt":"Her tarafında; çevreleyen","e1":"Let's sit around the table.","e1t":"Masanın etrafında oturalım.","e2":"There is a fence around the garden.","e2t":"Bahçenin etrafında bir çit var."},{"w":"artist","tr":"sanatçı / ressam","te":"Noun","tt":"İsim","de":"A person who creates art, especially paintings","dt":"Sanat eserleri, özellikle resim yapan kişi","e1":"She is a talented artist.","e1t":"O yetenekli bir sanatçıdır.","e2":"Famous artist.","e2t":"Ünlü sanatçı."},{"w":"as","tr":"olarak","te":"Adverb/Conjunction","tt":"Zarf/Bağlaç","de":"Used to refer to the function or character","dt":"İşlev veya karaktere atıfta bulunmak için kullanılır","e1":"He works as a teacher.","e1t":"Öğretmen olarak çalışıyor.","e2":"She is as tall as me.","e2t":"O benim kadar uzun."},{"w":"at","tr":"...de / ...da","te":"Preposition","tt":"Edat","de":"Used to express location or time","dt":"Konum veya zaman ifade etmek için kullanılır","e1":"I am at school now.","e1t":"Şu an okuldayım.","e2":"See you at 8 o'clock.","e2t":"Saat 8'de görüşürüz."},{"w":"august","tr":"Ağustos","te":"Noun","tt":"İsim","de":"The eighth month of the year","dt":"Yılın sekizinci ayı","e1":"August is the last month of summer.","e1t":"Ağustos yazın son ayıdır.","e2":"It is dry in August.","e2t":"Ağustosta hava kurudur."},{"w":"autumn","tr":"sonbahar","te":"Noun","tt":"İsim","de":"The season between summer and winter","dt":"Yaz ile kış arasındaki mevsim","e1":"Autumn is a rainy season.","e1t":"Sonbahar yağmurlu bir mevsimdir.","e2":"I like the colors of autumn.","e2t":"Sonbaharın renklerini severim."},{"w":"ax / axe","tr":"balta","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool used for chopping wood","dt":"Odun kesmek için kullanılan araç","e1":"Use an axe to cut the wood.","e1t":"Odunu kesmek için balta kullan.","e2":"Sharp axe.","e2t":"Keskin balta."},{"w":"baby","tr":"bebek","te":"Noun","tt":"İsim","de":"A very young child","dt":"Çok küçük çocuk","e1":"The baby is sleeping in the bed.","e1t":"Bebek yatakta uyuyor.","e2":"What a cute baby!","e2t":"Ne tatlı bir bebek!"},{"w":"back","tr":"sırt","te":"Noun","tt":"İsim","de":"The part of the body opposite the chest","dt":"Göğsün karşısındaki vücut bölümü","e1":"My back hurts after work.","e1t":"İşten sonra sırtım ağrıyor.","e2":"Lie on your back.","e2t":"Sırt üstü yat."},{"w":"bad","tr":"kötü","te":"Adjective","tt":"Sıfat","de":"Not good; of poor quality","dt":"İyi olmayan; düşük kaliteli","e1":"I have a bad headache.","e1t":"Kötü bir baş ağrım var.","e2":"Smoking is a bad habit.","e2t":"Sigara içmek kötü bir alışkanlıktır."},{"w":"bag","tr":"çanta","te":"Noun","tt":"İsim","de":"A container used for carrying things","dt":"Eşya taşımak için kullanılan kap","e1":"My school bag is heavy.","e1t":"Okul çantam ağır.","e2":"What is in your bag?","e2t":"Çantanda ne var?"},{"w":"balcony","tr":"balkon","te":"Noun","tt":"İsim","de":"A platform on the outside of a building","dt":"Bir binanın dış kısmındaki platform","e1":"I drink tea on the balcony.","e1t":"Balkonda çay içerim.","e2":"Our balcony has a nice view.","e2t":"Balkonumuzun güzel bir manzarası var."},{"w":"ball","tr":"top","te":"Noun","tt":"İsim","de":"A round object used in games and sports","dt":"Oyun ve sporlarda kullanılan yuvarlak nesne","e1":"Throw the ball to me.","e1t":"Topu bana at.","e2":"The dog is playing with a red ball.","e2t":"Köpek kırmızı bir topla oynuyor."},{"w":"balloon","tr":"balon","te":"Noun","tt":"İsim","de":"A small colored rubber bag filled with air","dt":"Hava ile doldurulmuş renkli kauçuk torba","e1":"The child has a red balloon.","e1t":"Çocuğun kırmızı bir balonu var.","e2":"Fly a balloon.","e2t":"Balon uçurmak."},{"w":"banana","tr":"muz","te":"Noun","tt":"İsim","de":"A long curved fruit with a yellow skin","dt":"Sarı kabuklu, uzun ve eğri bir meyve","e1":"The monkey is eating a banana.","e1t":"Maymun bir muz yiyor.","e2":"I like banana milk.","e2t":"Muzlu sütü severim."},{"w":"bandage","tr":"bandaj / sargı bezi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strip of cloth used to wrap an injury","dt":"Yarayı sarmak için kullanılan kumaş şeridi","e1":"He has a bandage on his arm.","e1t":"Kolunda bir bandaj var.","e2":"White bandage.","e2t":"Beyaz bandaj."},{"w":"bank","tr":"banka","te":"Noun","tt":"İsim","de":"A place for money","dt":"Para yatırılan yer","e1":"Where is the bank?","e1t":"Banka nerede?","e2":"I go to the bank.","e2t":"Bankaya giderim."},{"w":"barber","tr":"berber","te":"Noun","tt":"İsim","de":"A person whose job is to cut men's hair","dt":"İşi erkek saçı kesmek olan kişi","e1":"I am going to the barber.","e1t":"Berbere gidiyorum.","e2":"Good barber.","e2t":"İyi berber."},{"w":"basketball","tr":"basketbol","te":"Noun","tt":"İsim","de":"A game where you throw a ball through a hoop","dt":"Topu çemberden geçirdiğiniz bir oyun","e1":"Basketball is popular in America.","e1t":"Basketbol Amerika'da popülerdir.","e2":"He is very tall, he plays basketball.","e2t":"O çok uzun boylu, basketbol oynuyor."},{"w":"bathroom","tr":"banyo","te":"Noun","tt":"İsim","de":"A room with a bath or shower and a toilet","dt":"Küvet veya duş ve tuvaleti olan oda","e1":"I wash my hands in the bathroom.","e1t":"Ellerimi banyoda yıkarım.","e2":"Where is the bathroom?","e2t":"Banyo nerede?"},{"w":"beach","tr":"plaj","te":"Noun","tt":"İsim","de":"A sandy area next to the sea","dt":"Deniz kenarındaki kumlu alan","e1":"I want to go to the beach.","e1t":"Plaja gitmek istiyorum.","e2":"The beach is very crowded.","e2t":"Plaj çok kalabalık."},{"w":"beachball","tr":"plaj topu","te":"Noun","tt":"İsim","de":"A large light ball for playing on the beach","dt":"Plajda oynamak için kullanılan hafif, büyük top","e1":"We are playing with a beachball.","e1t":"Bir plaj topuyla oynuyoruz.","e2":"Colorful beachball.","e2t":"Renkli plaj topu."},{"w":"beautiful","tr":"güzel","te":"Adjective","tt":"Sıfat","de":"Pleasing the senses or mind aesthetically","dt":"Duyulara veya zihne estetik olarak hoş gelen","e1":"You have a beautiful house.","e1t":"Güzel bir evin var.","e2":"The flowers are beautiful.","e2t":"Çiçekler güzel."},{"w":"because","tr":"çünkü","te":"Conjunction","tt":"Bağlaç","de":"For the reason that","dt":"Bir sebepten dolayı","e1":"I am happy because it is sunny.","e1t":"Mutluyum çünkü hava güneşli.","e2":"He is late because of traffic.","e2t":"Trafik yüzünden geç kaldı."},{"w":"bed","tr":"yatak","te":"Noun","tt":"İsim","de":"A piece of furniture used for sleeping on","dt":"Üzerinde uyumak için kullanılan bir mobilya","e1":"I go to bed at 11 PM.","e1t":"Gece 11'de yatarım (yatağa giderim).","e2":"The bed is very soft.","e2t":"Yatak çok yumuşak."},{"w":"bedroom","tr":"yatak odası","te":"Noun","tt":"İsim","de":"A room used for sleeping","dt":"Uyumak için kullanılan oda","e1":"I have a desk in my bedroom.","e1t":"Yatak odamda bir çalışma masam var.","e2":"My bedroom is upstairs.","e2t":"Yatak odam üst katta."},{"w":"beetle","tr":"böcek / kın kanatlı","te":"Noun","tt":"İsim","de":"An insect with a hard shell","dt":"like back","e1":"Sert kabuk benzeri sırtı olan böcek","e1t":"There is a beetle on the leaf.","e2":"Yaprağın üzerinde bir böcek var.","e2t":"Black beetle."},{"w":"behind","tr":"arkasında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"At or to the back of","dt":"Bir şeyin arkasında veya gerisinde","e1":"The cat is behind the sofa.","e1t":"Kedi kanepenin arkasında.","e2":"Who is standing behind you?","e2t":"Arkanda kim duruyor?"},{"w":"bell","tr":"zil / çan","te":"Noun","tt":"İsim","de":"A hollow metal object that makes a ringing sound","dt":"Çınlama sesi çıkaran içi boş metal nesne","e1":"Ring the bell, please.","e1t":"Zili çalın, lütfen.","e2":"Door bell.","e2t":"Kapı zili."},{"w":"below","tr":"aşağıda","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"In a lower place or position","dt":"Daha alçak bir yerde veya konumda","e1":"The temperature is below zero.","e1t":"Sıcaklık sıfırın altında.","e2":"Write your name below.","e2t":"İsmini aşağıya yaz."},{"w":"belt","tr":"kemer","te":"Noun","tt":"İsim","de":"A strip of leather worn around the waist","dt":"Bel etrafına takılan deri şerit","e1":"I need a belt for these pants.","e1t":"Bu pantolon için bir kemere ihtiyacım var.","e2":"This is a brown leather belt.","e2t":"Bu kahverengi deri bir kemer."},{"w":"bench","tr":"bank / uzun oturak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long seat for several people","dt":"Birkaç kişilik uzun oturak","e1":"Sit on the park bench.","e1t":"Parktaki banka otur.","e2":"Wooden bench.","e2t":"Ahşap bank."},{"w":"between","tr":"arasında","te":"Preposition","tt":"Edat","de":"In the space separating two things","dt":"İki şeyi ayıran boşlukta","e1":"The bank is between the cafe and the shop.","e1t":"Banka, kafe ve dükkanın arasındadır.","e2":"Sit between your parents.","e2t":"Ebeveynlerinin arasına otur."},{"w":"bib","tr":"önlük (bebek)","te":"Noun","tt":"İsim","de":"A piece of cloth tied under a baby's chin while eating","dt":"Yemek yerken bebeğin çenesinin altına bağlanan kumaş","e1":"Put the bib on the baby.","e1t":"Bebeğe önlüğü tak.","e2":"Clean bib.","e2t":"Temiz önlük."},{"w":"big","tr":"büyük","te":"Adjective","tt":"Sıfat","de":"Large in size or amount","dt":"Boyut veya miktar olarak büyük","e1":"They live in a big house.","e1t":"Büyük bir evde yaşıyorlar.","e2":"That elephant is very big.","e2t":"O fil çok büyük."},{"w":"bike","tr":"bisiklet","te":"Noun","tt":"İsim","de":"A vehicle with two wheels that you ride","dt":"Bindiğiniz iki tekerlekli taşıt","e1":"He rides his bike to work.","e1t":"İşine bisikletiyle gider.","e2":"My bike is blue.","e2t":"Bisikletim mavi."},{"w":"bill","tr":"fatura","te":"Noun","tt":"İsim","de":"A piece of paper that shows how much money you owe","dt":"Ne kadar borcun olduğunu gösteren kağıt parçası","e1":"I need to pay the electricity bill.","e1t":"Elektrik faturasını ödemem gerekiyor.","e2":"Can I have the bill, please?","e2t":"Hesabı (faturayı) alabilir miyim lütfen?"},{"w":"bird","tr":"kuş","te":"Noun","tt":"İsim","de":"An animal with feathers and wings","dt":"Tüyleri ve kanatları olan bir hayvan","e1":"The birds are singing in the trees.","e1t":"Kuşlar ağaçlarda şarkı söylüyor.","e2":"Look at that beautiful blue bird.","e2t":"Şu güzel mavi kuşa bak."},{"w":"birthday","tr":"doğum günü","te":"Noun","tt":"İsim","de":"The day on which a person was born","dt":"Bir kişinin doğduğu gün","e1":"When is your birthday?","e1t":"Doğum günün ne zaman?","e2":"Happy birthday to you!","e2t":"Doğum günün kutlu olsun!"},{"w":"black","tr":"siyah","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The darkest color, like night","dt":"Gece gibi en koyu renk","e1":"He wears a black suit.","e1t":"Siyah bir takım elbise giyiyor.","e2":"I have a black cat.","e2t":"Siyah bir kedim var."},{"w":"blackberry","tr":"böğürtlen","te":"Noun","tt":"İsim","de":"A small black fruit that grows on bushes","dt":"Çalılarda yetişen küçük siyah meyve","e1":"I like blackberry jam.","e1t":"Böğürtlen reçelini severim.","e2":"Sweet blackberry.","e2t":"Tatlı böğürtlen."},{"w":"blender","tr":"blender / karıştırıcı","te":"Noun","tt":"İsim","de":"A kitchen machine used for mixing food","dt":"Yemekleri karıştırmak için kullanılan mutfak aleti","e1":"Use the blender to make a smoothie.","e1t":"Smoothie yapmak için blenderı kullan.","e2":"Kitchen blender.","e2t":"Mutfak blenderı."},{"w":"blocks","tr":"bloklar / küpler","te":"Noun","tt":"İsim (Plural)","de":"Toy cubes for building","dt":"İnşa etmek için kullanılan oyuncak küpler","e1":"Playing with wooden blocks.","e1t":"Ahşap bloklarla oynamak.","e2":"Build a tower with blocks.","e2t":"Bloklarla kule yapmak."},{"w":"blouse","tr":"bluz","te":"Noun","tt":"İsim","de":"A shirt for women","dt":"Kadınlar için gömlek","e1":"She is wearing a white blouse.","e1t":"Beyaz bir bluz giyiyor.","e2":"Silk blouse.","e2t":"İpek bluz."},{"w":"blue","tr":"mavi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of the sky or sea","dt":"Gökyüzünün veya denizin rengi","e1":"The sky is blue today.","e1t":"Bugün gökyüzü mavi.","e2":"I have blue eyes.","e2t":"Mavi gözlerim var."},{"w":"blueberry","tr":"yaban mersini","te":"Noun","tt":"İsim","de":"A small blue fruit","dt":"Küçük mavi meyve","e1":"I eat blueberries for breakfast.","e1t":"Kahvaltıda yaban mersini yerim.","e2":"Fresh blueberry.","e2t":"Taze yaban mersini."},{"w":"boat","tr":"tekne / bot","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small ship","dt":"Küçük gemi","e1":"Let's go by boat.","e1t":"Tekneyle gidelim.","e2":"Fishing boat.","e2t":"Balıkçı teknesi."},{"w":"body","tr":"vücut","te":"Noun","tt":"İsim","de":"The whole physical structure of a person","dt":"Bir insanın tüm fiziksel yapısı","e1":"Exercise is good for your body.","e1t":"Egzersiz vücudunuz için iyidir.","e2":"Keep your body healthy.","e2t":"Vücudunu sağlıklı tut."},{"w":"book","tr":"kitap","te":"Noun","tt":"İsim","de":"A set of printed pages fastened together inside a cover","dt":"Bir kapak içinde birleştirilmiş basılı sayfalar seti","e1":"I am reading an interesting book.","e1t":"İlginç bir kitap okuyorum.","e2":"Put the book in your bag.","e2t":"Kitabı çantana koy."},{"w":"bookshop","tr":"kitapçı","te":"Noun","tt":"İsim","de":"A shop that sells books","dt":"Kitap satan dükkan","e1":"I am going to the bookshop to buy a novel.","e1t":"Roman almak için kitapçıya gidiyorum.","e2":"The bookshop is next to the cafe.","e2t":"Kitapçı kafenin yanındadır."},{"w":"boots","tr":"bot / çizme","te":"Noun","tt":"İsim (Plural)","de":"Strong shoes that cover the foot and ankle","dt":"Ayağı ve bileği kapatan sağlam ayakkabı","e1":"Wear your rain boots.","e1t":"Yağmur çizmelerini giy.","e2":"Winter boots.","e2t":"Kışlık botlar."},{"w":"boss","tr":"patron","te":"Noun","tt":"İsim","de":"A person who is in charge of a worker","dt":"Bir işçiden sorumlu olan kişi","e1":"My boss is very kind.","e1t":"Patronum çok nazik.","e2":"I have a meeting with my boss.","e2t":"Patronumla bir toplantım var."},{"w":"both","tr":"ikisi","te":"Pronoun/Determiner","tt":"Zamir/Belirleyici","de":"Two people or things together","dt":"İki kişi veya şey birlikte","e1":"I like both of them.","e1t":"İkisini de seviyorum.","e2":"Use both hands.","e2t":"İki elini de kullan."},{"w":"boy","tr":"erkek çocuk","te":"Noun","tt":"İsim","de":"A male child","dt":"Erkek çocuk","e1":"The boy is playing with a ball.","e1t":"Çocuk topla oynuyor.","e2":"He is a clever boy.","e2t":"O zeki bir çocuk."},{"w":"brain","tr":"beyin","te":"Noun","tt":"İsim","de":"The organ used for thinking","dt":"Düşünmek için kullanılan organ","e1":"Use your brain to solve the problem.","e1t":"Problemi çözmek için beynini kullan.","e2":"The brain is a complex organ.","e2t":"Beyin karmaşık bir organdır."},{"w":"bread","tr":"ekmek","te":"Noun","tt":"İsim","de":"A common food made from flour and water","dt":"Un ve sudan yapılan yaygın bir yiyecek","e1":"Buy a loaf of bread, please.","e1t":"Lütfen bir somun ekmek al.","e2":"I like fresh, warm bread.","e2t":"Taze ve sıcak ekmeği severim."},{"w":"break","tr":"mola","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short period of rest","dt":"Kısa dinlenme süresi","e1":"Let's take a ten","e1t":"minute break.","e2":"On dakikalık bir mola verelim.","e2t":"I am on my lunch break."},{"w":"breakfast","tr":"kahvaltı","te":"Noun","tt":"İsim","de":"The first meal of the day, eaten in the morning","dt":"Sabah yenen günün ilk öğünü","e1":"What did you eat for breakfast?","e1t":"Kahvaltıda ne yedin?","e2":"Breakfast is the most important meal.","e2t":"Kahvaltı en önemli öğündür."},{"w":"bridge","tr":"köprü","te":"Noun","tt":"İsim","de":"A structure built over a river or road","dt":"Nehir veya yol üzerine inşa edilen yapı","e1":"The car is crossing the bridge.","e1t":"Araba köprüden geçiyor.","e2":"This is a very old bridge.","e2t":"Bu çok eski bir köprü."},{"w":"bring","tr":"getirmek","te":"Verb","tt":"Fiil","de":"To take something to a place or person","dt":"Bir şeyi bir yere veya kişiye götürmek","e1":"Bring me a glass of water.","e1t":"Bana bir bardak su getir.","e2":"Did you bring your bag?","e2t":"Çantanı getirdin mi?"},{"w":"broccoli","tr":"brokoli","te":"Noun","tt":"İsim","de":"A green vegetable that looks like a small tree","dt":"Küçük bir ağaca benzeyen yeşil sebze","e1":"Broccoli is very healthy.","e1t":"Brokoli çok sağlıklıdır.","e2":"Green broccoli.","e2t":"Yeşil brokoli."},{"w":"broom","tr":"süpürge","te":"Noun","tt":"İsim","de":"A brush with a long handle for sweeping floors","dt":"Yerleri süpürmek için uzun saplı fırça","e1":"Use the broom to clean the floor.","e1t":"Yeri temizlemek için süpürgeyi kullan.","e2":"New broom.","e2t":"Yeni süpürge."},{"w":"brother","tr":"erkek kardeş","te":"Noun","tt":"İsim","de":"A boy or man who has the same parents","dt":"Aynı ebeveynlere sahip erkek veya adam","e1":"My brother plays football.","e1t":"Erkek kardeşim futbol oynar.","e2":"Do you have a brother?","e2t":"Erkek kardeşin var mı?"},{"w":"brown","tr":"kahverengi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of earth or coffee","dt":"Toprağın veya kahvenin rengi","e1":"The dog has brown fur.","e1t":"Köpeğin kahverengi tüyleri var.","e2":"I have brown shoes.","e2t":"Kahverengi ayakkabılarım var."},{"w":"bus","tr":"otobüs","te":"Noun","tt":"İsim","de":"A large motor vehicle carrying many passengers","dt":"Çok sayıda yolcu taşıyan büyük motorlu taşıt","e1":"I catch the bus at 8 o'clock.","e1t":"Otobüse saat 8'de binerim.","e2":"The bus is full of people.","e2t":"Otobüs insanlarla dolu."},{"w":"bus stop","tr":"otobüs durağı","te":"Noun","tt":"İsim","de":"A place where a bus regularly stops","dt":"Otobüsün düzenli durduğu yer","e1":"Wait for me at the bus stop.","e1t":"Beni otobüs durağında bekle.","e2":"Where is the bus stop?","e2t":"Otobüs durağı nerede?"},{"w":"but","tr":"ama","te":"Conjunction","tt":"Bağlaç","de":"Used to introduce a contrast","dt":"Bir zıtlık sunmak için kullanılır","e1":"I am tired but happy.","e1t":"Yorgunum ama mutluyum.","e2":"She studied hard but failed.","e2t":"Çok çalıştı ama başarısız oldu."},{"w":"buy","tr":"satın almak","te":"Verb","tt":"Fiil","de":"To get something by paying money","dt":"Para ödeyerek bir şey elde etmek","e1":"I want to buy a new car.","e1t":"Yeni bir araba satın almak istiyorum.","e2":"Where did you buy that shirt?","e2t":"O gömleği nereden aldın?"},{"w":"bye","tr":"bay bay","te":"Exclamation","tt":"Ünlem","de":"Informal way of saying goodbye","dt":"Hoşça kal demenin resmi olmayan yolu","e1":"Bye! Have a nice day.","e1t":"Bay bay! İyi günler.","e2":"Bye bye, see you later.","e2t":"Bay bay, sonra görüşürüz."},{"w":"cafe","tr":"kafe","te":"Noun","tt":"İsim","de":"A small restaurant where you can buy drinks and snacks","dt":"İçecek ve atıştırmalık alabileceğiniz küçük restoran","e1":"Let's meet at the cafe.","e1t":"Kafede buluşalım.","e2":"The cafe is near the park.","e2t":"Kafe parkın yakınında."},{"w":"cage","tr":"kafes","te":"Noun/Verb","tt":"İsim/Fiil","de":"A structure of bars to keep animals","dt":"Hayvanları tutmak için parmaklıklı yapı","e1":"The bird is in the cage.","e1t":"Kuş kafeste.","e2":"A big cage.","e2t":"Büyük bir kafes."},{"w":"call","tr":"aramak","te":"Verb","tt":"Fiil","de":"To phone someone or cry out","dt":"Birine telefon etmek veya seslenmek","e1":"Call me later, please.","e1t":"Lütfen beni sonra ara.","e2":"He called my name.","e2t":"Benim ismimi çağırdı."},{"w":"camera","tr":"fotoğraf makinesi","te":"Noun","tt":"İsim","de":"A device for taking photos or videos","dt":"Fotoğraf veya video çekmek için kullanılan cihaz","e1":"Smile for the camera!","e1t":"Kamera için gülümse!","e2":"I bought a new digital camera.","e2t":"Yeni bir dijital kamera aldım."},{"w":"canary","tr":"kanarya","te":"Noun","tt":"İsim","de":"A small yellow bird that sings","dt":"Öten küçük sarı kuş","e1":"My canary sings every morning.","e1t":"Kanaryam her sabah öter.","e2":"Yellow canary.","e2t":"Sarı kanarya."},{"w":"canoe","tr":"kano","te":"Noun/Verb","tt":"İsim/Fiil","de":"A light narrow boat","dt":"Hafif dar tekne","e1":"Let's go for a ride in the canoe.","e1t":"Kanoyla gezintiye çıkalım.","e2":"River canoe.","e2t":"Nehir kanosu."},{"w":"car","tr":"araba","te":"Noun","tt":"İsim","de":"A road vehicle with four wheels","dt":"Dört tekerlekli yol taşıtı","e1":"My father washes the car on Sundays.","e1t":"Babam pazarları arabayı yıkar.","e2":"He drives a red car.","e2t":"Kırmızı bir araba sürüyor."},{"w":"caravan","tr":"karavan","te":"Noun","tt":"İsim","de":"A vehicle people can live in while traveling","dt":"Seyahat ederken içinde yaşanabilen araç","e1":"We travel in our caravan.","e1t":"Karavanımızla seyahat ediyoruz.","e2":"New caravan.","e2t":"Yeni karavan."},{"w":"care","tr":"bakım","te":"Noun/Verb","tt":"İsim/Fiil","de":"The process of looking after someone","dt":"Birine bakma süreci","e1":"He needs medical care.","e1t":"Onun tıbbi bakıma ihtiyacı var.","e2":"Take care of yourself.","e2t":"Kendine iyi bak."},{"w":"carrot","tr":"havuç","te":"Noun","tt":"İsim","de":"A long orange root vegetable","dt":"Uzun, turuncu bir kök sebze","e1":"Rabbits love eating carrots.","e1t":"Tavşanlar havuç yemeyi çok sever.","e2":"Carrot juice is orange.","e2t":"Havuç suyu turuncudur."},{"w":"cash","tr":"nakit","te":"Noun","tt":"İsim","de":"Money in the form of notes and coins","dt":"Kağıt ve madeni para formundaki para","e1":"Do you have any cash?","e1t":"Hiç nakit paran var mı?","e2":"I want to pay in cash.","e2t":"Nakit ödemek istiyorum."},{"w":"cat","tr":"kedi","te":"Noun","tt":"İsim","de":"A small furry animal kept as a pet","dt":"Evcil hayvan olarak beslenen küçük tüylü hayvan","e1":"The cat is sleeping on the chair.","e1t":"Kedi sandalyenin üzerinde uyuyor.","e2":"I have two cats.","e2t":"İki kedim var."},{"w":"caterpillar","tr":"tırtıl","te":"Noun","tt":"İsim","de":"The larva of a butterfly","dt":"Kelebek larvası","e1":"The caterpillar is eating a leaf.","e1t":"Tırtıl yaprak yiyor.","e2":"Green caterpillar.","e2t":"Yeşil tırtıl."},{"w":"cent","tr":"sent / kuruş","te":"Noun","tt":"İsim","de":"A unit of money equal to 1/100 of a dollar or euro","dt":"Dolar veya euronun yüzde biri değerindeki para birimi","e1":"It costs 50 cents.","e1t":"50 sent tutuyor.","e2":"I don't have a cent.","e2t":"Bir kuruşum bile yok."},{"w":"cereal","tr":"mısır gevreği / tahıl","te":"Noun","tt":"İsim","de":"Food made from grain, eaten with milk for breakfast","dt":"Kahvaltıda sütle yenen tahıl yiyeceği","e1":"I eat cereal for breakfast.","e1t":"Kahvaltıda mısır gevreği yerim.","e2":"Bowl of cereal.","e2t":"Bir kase mısır gevreği."},{"w":"chair","tr":"sandalye","te":"Noun","tt":"İsim","de":"A piece of furniture for one person to sit on","dt":"Bir kişinin oturması için bir mobilya","e1":"Please sit on that chair.","e1t":"Lütfen şu sandalyeye oturun.","e2":"This chair is very comfortable.","e2t":"Bu sandalye çok rahat."},{"w":"chalk","tr":"tebeşir","te":"Noun/Verb","tt":"İsim/Fiil","de":"Soft white limestone for writing on boards","dt":"Tahtaya yazmak için kullanılan kireç taşı","e1":"Write with white chalk.","e1t":"Beyaz tebeşirle yaz.","e2":"A piece of chalk.","e2t":"Bir parça tebeşir."},{"w":"chef","tr":"aşçı","te":"Noun","tt":"İsim","de":"A professional cook in a restaurant","dt":"Restorandaki profesyonel aşçı","e1":"The chef prepared a special meal.","e1t":"Aşçı özel bir yemek hazırladı.","e2":"I want to talk to the chef.","e2t":"Aşçıyla konuşmak istiyorum."},{"w":"cherry","tr":"kiraz","te":"Noun","tt":"İsim","de":"A small round red fruit","dt":"Küçük yuvarlak kırmızı meyve","e1":"I like cherry pie.","e1t":"Kirazlı turtayı severim.","e2":"Sweet cherry.","e2t":"Tatlı kiraz."},{"w":"chess","tr":"satranç","te":"Noun","tt":"İsim","de":"A game for two people played on a board","dt":"Tahta üzerinde iki kişiyle oynanan oyun","e1":"Can you play chess?","e1t":"Satranç oynayabilir misin?","e2":"Chess club.","e2t":"Satranç kulübü."},{"w":"chicken","tr":"tavuk","te":"Noun","tt":"İsim","de":"A common farm bird kept for its meat and eggs","dt":"Eti ve yumurtası için beslenen yaygın bir çiftlik kuşu","e1":"We had grilled chicken for lunch.","e1t":"Öğle yemeğinde ızgara tavuk yedik.","e2":"The chicken is in the garden.","e2t":"Tavuk bahçede."},{"w":"city","tr":"şehir","te":"Noun","tt":"İsim","de":"A large and important town","dt":"Büyük ve önemli yerleşim yeri","e1":"London is a big city.","e1t":"Londra büyük bir şehirdir.","e2":"I like living in the city.","e2t":"Şehirde yaşamayı seviyorum."},{"w":"classroom","tr":"sınıf","te":"Noun","tt":"İsim","de":"A room in a school where lessons take place","dt":"Okulda derslerin yapıldığı oda","e1":"Don't talk in the classroom.","e1t":"Sınıfta konuşma.","e2":"Our classroom is on the second floor.","e2t":"Sınıfımız ikinci katta."},{"w":"clean","tr":"temiz","te":"Adjective","tt":"Sıfat","de":"Free from dirt, marks, or stains","dt":"Kirden, izden veya lekeden arınmış","e1":"My room is very clean.","e1t":"Odam çok temiz.","e2":"Use a clean towel, please.","e2t":"Lütfen temiz bir havlu kullan."},{"w":"clinic","tr":"klinik","te":"Noun","tt":"İsim","de":"A place where people go for medical treatment","dt":"İnsanların tıbbi tedavi için gittiği yer","e1":"The clinic is closed on Sundays.","e1t":"Klinik pazar günleri kapalıdır.","e2":"I have an appointment at the clinic.","e2t":"Klinikte bir randevum var."},{"w":"close","tr":"kapatmak","te":"Verb","tt":"Fiil","de":"To move something to cover an opening","dt":"Bir açıklığı örtmek için bir şeyi hareket ettirmek","e1":"Please close your books.","e1t":"Lütfen kitaplarınızı kapatın.","e2":"Close the door behind you.","e2t":"Arkandan kapıyı kapat."},{"w":"clothes","tr":"kıyafet","te":"Noun","tt":"İsim","de":"Things such as shirts and pants that you wear","dt":"Gömlek ve pantolon gibi giydiğiniz şeyler","e1":"Put your dirty clothes in the basket.","e1t":"Kirli kıyafetlerini sepete koy.","e2":"I need to buy new clothes.","e2t":"Yeni kıyafetler almam gerekiyor."},{"w":"cloud","tr":"bulut","te":"Noun","tt":"İsim","de":"A white or grey mass in the sky","dt":"Gökyüzündeki beyaz veya gri kütle","e1":"There are no clouds in the sky.","e1t":"Gökyüzünde hiç bulut yok.","e2":"The sun is behind the clouds.","e2t":"Güneş bulutların arkasında."},{"w":"cloudy","tr":"bulutlu","te":"Adjective","tt":"Sıfat","de":"With many clouds in the sky","dt":"Gökyüzünde çok sayıda bulutun olması","e1":"The sky is very cloudy.","e1t":"Gökyüzü çok bulutlu.","e2":"It is a cloudy but warm day.","e2t":"Bulutlu ama ılık bir gün."},{"w":"clover","tr":"yonca","te":"Noun","tt":"İsim","de":"A small plant with three or four leaves","dt":"Üç veya dört yapraklı küçük bitki","e1":"I found a four","e1t":"leaf clover.","e2":"Dört yapraklı bir yonca buldum.","e2t":"Green clover."},{"w":"clown","tr":"palyaço","te":"Noun","tt":"İsim","de":"A person who wears funny clothes to make people laugh","dt":"İnsanları güldürmek için komik giyinen kişi","e1":"The children like the clown.","e1t":"Çocuklar palyaçoyu seviyor.","e2":"Funny clown.","e2t":"Komik palyaço."},{"w":"coat","tr":"mont","te":"Noun","tt":"İsim","de":"An outer piece of clothing worn for warmth","dt":"Isınmak için giyilen dış kıyafet","e1":"Put on your coat, it's snowing.","e1t":"Montunu giy, kar yağıyor.","e2":"I left my coat in the car.","e2t":"Montumu arabada bıraktım."},{"w":"coconut","tr":"Hindistan cevizi","te":"Noun","tt":"İsim","de":"A large nut with a hard shell and white flesh","dt":"Sert kabuklu ve beyaz etli büyük somun","e1":"I like coconut milk.","e1t":"Hindistan cevizi sütünü severim.","e2":"Fresh coconut.","e2t":"Taze Hindistan cevizi."},{"w":"coffee","tr":"kahve","te":"Noun","tt":"İsim","de":"A dark brown drink made from ground beans","dt":"Öğütülmüş çekirdeklerden yapılan koyu kahverengi içecek","e1":"I drink coffee every morning.","e1t":"Her sabah kahve içerim.","e2":"Coffee without sugar is bitter.","e2t":"Şekersiz kahve acıdır."},{"w":"cold","tr":"soğuk","te":"Adjective","tt":"Sıfat","de":"Having a low temperature","dt":"Düşük sıcaklığa sahip olma","e1":"I like cold water in summer.","e1t":"Yazın soğuk suyu severim.","e2":"It is very cold outside.","e2t":"Dışarısı çok soğuk."},{"w":"colleague","tr":"iş arkadaşı","te":"Noun","tt":"İsim","de":"A person that you work with","dt":"Birlikte çalıştığınız kişi","e1":"She is my favorite colleague.","e1t":"O benim en sevdiğim iş arkadaşım.","e2":"I am going to lunch with my colleagues.","e2t":"İş arkadaşlarımla öğle yemeğine gidiyorum."},{"w":"color","tr":"renk","te":"Noun","tt":"İsim","de":"Red, blue, green, etc.","dt":"Kırmızı, mavi, yeşil vb.","e1":"What is your favorite color?","e1t":"En sevdiğin renk ne?","e2":"I like the color of your car.","e2t":"Arabanın rengini sevdim."},{"w":"come","tr":"gelmek","te":"Verb","tt":"Fiil","de":"To move towards a person or place","dt":"Bir kişiye veya yere doğru hareket etmek","e1":"Please come here.","e1t":"Lütfen buraya gel.","e2":"He comes home at 6 PM.","e2t":"Akşam 6'da eve gelir."},{"w":"company","tr":"şirket","te":"Noun","tt":"İsim","de":"An organization that sells goods or services","dt":"Mal veya hizmet satan kuruluş","e1":"He works for a software company.","e1t":"Bir yazılım şirketi için çalışıyor.","e2":"Our company is very successful.","e2t":"Şirketimiz çok başarılı."},{"w":"compass","tr":"pusula","te":"Noun","tt":"İsim","de":"A tool that shows directions (North, South, etc.)","dt":"Yönleri gösteren araç","e1":"Use a compass to find the way.","e1t":"Yolu bulmak için pusula kullan.","e2":"Magnetic compass.","e2t":"Manyetik pusula."},{"w":"computer","tr":"bilgisayar","te":"Noun","tt":"İsim","de":"An electronic device for storing and processing data","dt":"Veri depolayan ve işleyen elektronik cihaz","e1":"I use a computer for my work.","e1t":"İşim için bilgisayar kullanırım.","e2":"Turn off the computer.","e2t":"Bilgisayarı kapat."},{"w":"cook","tr":"yemek yapmak","te":"Verb","tt":"Fiil","de":"To prepare food by heating it","dt":"Yiyecekleri ısıtarak hazırlamak","e1":"My father cooks dinner.","e1t":"Akşam yemeğini babam pişirir.","e2":"I like to cook Italian food.","e2t":"İtalyan yemekleri yapmayı severim."},{"w":"cool","tr":"serin","te":"Adjective","tt":"Sıfat","de":"Fairly cold in a pleasant way","dt":"Hoş bir şekilde oldukça soğuk","e1":"The evening air is cool.","e1t":"Akşam havası serin.","e2":"Let's sit in a cool place.","e2t":"Serin bir yerde oturalım."},{"w":"cork","tr":"mantar (şişe)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A light material used to close bottles","dt":"Şişeleri kapatmak için kullanılan hafif madde","e1":"Pull the cork out of the bottle.","e1t":"Şişenin mantarını çekip çıkar.","e2":"Wine cork.","e2t":"Şarap mantarı."},{"w":"country","tr":"ülke","te":"Noun","tt":"İsim","de":"An area of land with its own government","dt":"Kendi hükümeti olan kara alanı","e1":"Which country are you from?","e1t":"Hangi ülkedensin?","e2":"Turkey is a beautiful country.","e2t":"Türkiye güzel bir ülkedir."},{"w":"cow","tr":"inek","te":"Noun","tt":"İsim","de":"A large farm animal kept for milk or meat","dt":"Süt veya et için beslenen büyük çiftlik hayvanı","e1":"The cow gives fresh milk.","e1t":"İnek taze süt verir.","e2":"There are many cows on the farm.","e2t":"Çiftlikte birçok inek var."},{"w":"crayon","tr":"pastel boya","te":"Noun","tt":"İsim","de":"A stick of colored wax used for drawing","dt":"Çizim için kullanılan renkli balmumu çubuk","e1":"Use a blue crayon.","e1t":"Mavi bir pastel boya kullan.","e2":"Box of crayons.","e2t":"Pastel boya kutusu."},{"w":"credit card","tr":"kredi kartı","te":"Noun","tt":"İsim","de":"A small plastic card used to pay for things","dt":"Ödeme yapmak için kullanılan küçük plastik kart","e1":"Can I pay by credit card?","e1t":"Kredi kartıyla ödeyebilir miyim?","e2":"I lost my credit card.","e2t":"Kredi kartımı kaybettim."},{"w":"cricket","tr":"cırcır böceği / kriket (spor)","te":"Noun","tt":"İsim","de":"An insect that makes a loud noise at night; or a sport","dt":"Gece ses çıkaran böcek; veya bir spor dalı","e1":"I hear crickets in the garden.","e1t":"Bahçede cırcır böceklerini duyuyorum.","e2":"Play cricket.","e2t":"Kriket oynamak."},{"w":"cube","tr":"küp","te":"Noun/Verb","tt":"İsim/Fiil","de":"A solid object with six equal square sides","dt":"Altı eşit kare yüzü olan katı nesne","e1":"An ice cube.","e1t":"Buz küpü.","e2":"A wooden cube.","e2t":"Ahşap küp."},{"w":"cup","tr":"bardak / fincan","te":"Noun","tt":"İsim","de":"A small container used for drinking tea or coffee","dt":"Çay veya kahve içmek için kullanılan küçük kap","e1":"Can I have a cup of coffee?","e1t":"Bir fincan kahve alabilir miyim?","e2":"Put the cup on the table.","e2t":"Fincanı masaya koy."},{"w":"cycling","tr":"bisiklet sürme","te":"Noun","tt":"İsim","de":"The activity of riding a bicycle","dt":"Bisiklete binme aktivitesi","e1":"Cycling is my favorite hobby.","e1t":"Bisiklet sürmek en sevdiğim hobimdir.","e2":"There is a cycling path in the park.","e2t":"Parkta bir bisiklet yolu var."},{"w":"dad","tr":"baba","te":"Noun","tt":"İsim","de":"Informal word for father","dt":"Babanın samimi söylenişi","e1":"My dad is at home.","e1t":"Babam evde.","e2":"Best dad.","e2t":"En iyi baba."},{"w":"daisy","tr":"papatya","te":"Noun","tt":"İsim","de":"A small flower with white petals and a yellow center","dt":"Beyaz yapraklı ve sarı merkezli küçük çiçek","e1":"She is picking daisies.","e1t":"Papatya topluyor.","e2":"White daisy.","e2t":"Beyaz papatya."},{"w":"dance","tr":"dans","te":"Noun/Verb","tt":"İsim/Fiil","de":"To move your body to music","dt":"Müziğe göre vücudunu hareket ettirmek","e1":"Do you want to dance with me?","e1t":"Benimle dans etmek ister misin?","e2":"They are doing a traditional dance.","e2t":"Geleneksel bir dans yapıyorlar."},{"w":"daughter","tr":"kız evlat","te":"Noun","tt":"İsim","de":"A person's female child","dt":"Bir kişinin kız çocuğu","e1":"My daughter is a student.","e1t":"Kızım bir öğrencidir.","e2":"She is their eldest daughter.","e2t":"O onların en büyük kızı."},{"w":"day","tr":"gün","te":"Noun","tt":"İsim","de":"A period of 24 hours","dt":"24 saatlik zaman dilimi","e1":"Have a nice day!","e1t":"İyi günler!","e2":"I work five days a week.","e2t":"Haftada beş gün çalışırım."},{"w":"december","tr":"Aralık","te":"Noun","tt":"İsim","de":"The twelfth and last month of the year","dt":"Yılın on ikinci ve son ayı","e1":"December is the end of the year.","e1t":"Aralık yılın sonudur.","e2":"It snows in December.","e2t":"Aralıkta kar yağar."},{"w":"deer","tr":"geyik","te":"Noun","tt":"İsim","de":"A wild animal with hooves and antlers","dt":"Toynaklı ve boynuzlu yabani hayvan","e1":"Look at the deer in the forest.","e1t":"Ormandaki geyiğe bak.","e2":"(Not: Tekili ve çoğulu aynıdır","e2t":"deer)."},{"w":"desert","tr":"çöl","te":"Noun","tt":"İsim","de":"A large dry area of land with sand","dt":"Kumlu, büyük ve kuru kara alanı","e1":"The Sahara is a huge desert.","e1t":"Sahra devasa bir çöldür.","e2":"It is very hot in the desert.","e2t":"Çölde hava çok sıcaktır."},{"w":"digger","tr":"kazıcı / ekskavatör","te":"Noun","tt":"İsim","de":"A machine used for digging","dt":"Kazmak için kullanılan makine","e1":"The digger is working on the road.","e1t":"Kazıcı yolda çalışıyor.","e2":"Toy digger.","e2t":"Oyuncak kepçe."},{"w":"dime","tr":"10 sentlik madeni para","te":"Noun","tt":"İsim","de":"A US coin worth ten cents","dt":"10 sent değerindeki ABD madeni parası","e1":"I have a dime in my pocket.","e1t":"Cebimde 10 sentlik var.","e2":"(Not: ABD para birimi birimi).","e2t":""},{"w":"dinner","tr":"akşam yemeği","te":"Noun","tt":"İsim","de":"The main meal of the day, eaten in the evening","dt":"Akşam yenen günün ana öğünü","e1":"We are having fish for dinner.","e1t":"Akşam yemeği için balık yiyoruz.","e2":"What time is dinner?","e2t":"Akşam yemeği saat kaçta?"},{"w":"dirty","tr":"kirli","te":"Adjective","tt":"Sıfat","de":"Covered or marked with an unclean substance","dt":"Temiz olmayan bir maddeyle kaplanmış veya işaretlenmiş","e1":"Your shoes are very dirty.","e1t":"Ayakkabıların çok kirli.","e2":"Don't touch the dirty floor.","e2t":"Kirli zemine dokunma."},{"w":"do","tr":"yapmak","te":"Verb","tt":"Fiil","de":"To perform an action or activity","dt":"Bir eylemi veya aktiviteyi gerçekleştirmek","e1":"I do my homework every day.","e1t":"Her gün ödevimi yaparım.","e2":"What do you do in your free time?","e2t":"Boş zamanlarında ne yaparsın?"},{"w":"doctor","tr":"doktor","te":"Noun","tt":"İsim","de":"A person who treats sick people","dt":"Hasta insanları tedavi eden kişi","e1":"You should see a doctor.","e1t":"Bir doktora görünmelisin.","e2":"The doctor is examining the patient.","e2t":"Doktor hastayı muayene ediyor."},{"w":"dog","tr":"köpek","te":"Noun","tt":"İsim","de":"A common animal kept as a pet or for work","dt":"Evcil hayvan veya iş için beslenen yaygın hayvan","e1":"My dog loves playing with a ball.","e1t":"Köpeğim topla oynamayı çok sever.","e2":"Don't be afraid, the dog is friendly.","e2t":"Korkma, köpek arkadaş canlısıdır."},{"w":"door","tr":"kapı","te":"Noun","tt":"İsim","de":"A barrier used to open or close an entrance","dt":"Bir girişi açmak veya kapatmak için kullanılan bariyer","e1":"Please close the door.","e1t":"Lütfen kapıyı kapat.","e2":"Someone is at the door.","e2t":"Kapıda biri var."},{"w":"dots","tr":"noktalar / benekler","te":"Noun","tt":"İsim (Plural)","de":"Small round marks","dt":"Küçük yuvarlak işaretler","e1":"A dress with white dots.","e1t":"Beyaz benekli bir elbise.","e2":"Join the dots.","e2t":"Noktaları birleştir."},{"w":"doughnut / donut","tr":"donat / çörek","te":"Noun","tt":"İsim","de":"A small fried cake with a hole in the middle","dt":"Ortası delik, küçük kızarmış kek","e1":"I want a chocolate doughnut.","e1t":"Çikolatalı bir donat istiyorum.","e2":"Sweet doughnut.","e2t":"Tatlı donat."},{"w":"dragonfly","tr":"yusufçuk","te":"Noun","tt":"İsim","de":"An insect with a long body and four wings","dt":"Uzun vücutlu ve dört kanatlı böcek","e1":"A blue dragonfly is flying.","e1t":"Mavi bir yusufçuk uçuyor.","e2":"Big dragonfly.","e2t":"Büyük yusufçuk."},{"w":"draw","tr":"çizmek","te":"Verb","tt":"Fiil","de":"To produce a picture with a pen or pencil","dt":"Kalem veya kurşun kalemle bir resim üretmek","e1":"Draw a picture of a house.","e1t":"Bir ev resmi çiz.","e2":"She likes to draw animals.","e2t":"Hayvan çizmeyi seviyor."},{"w":"dress","tr":"elbise","te":"Noun","tt":"İsim","de":"A one","dt":"piece garment for women","e1":"Kadınlar için tek parça giysi","e1t":"She bought a red dress for the party.","e2":"Parti için kırmızı bir elbise aldı.","e2t":"This dress is very beautiful."},{"w":"drink","tr":"içecek","te":"Noun","tt":"İsim","de":"A liquid that can be swallowed","dt":"Yutulabilen (içilebilen) bir sıvı","e1":"What would you like to drink?","e1t":"Ne içmek istersiniz?","e2":"Water is the best drink.","e2t":"Su en iyi içecektir."},{"w":"drive","tr":"sürmek","te":"Verb","tt":"Fiil","de":"To operate and control a motor vehicle","dt":"Motorlu bir aracı çalıştırmak ve kontrol etmek","e1":"Can you drive a car?","e1t":"Araba sürebiliyor musun?","e2":"He drives to work every day.","e2t":"Her gün işe arabayla gider."},{"w":"driver","tr":"sürücü","te":"Noun","tt":"İsim","de":"A person who drives a vehicle","dt":"Araç süren kişi","e1":"He is a bus driver.","e1t":"O bir otobüs şoförüdür.","e2":"The taxi driver was very friendly.","e2t":"Taksi şoförü çok arkadaş canlısıydı."},{"w":"duck","tr":"ördek","te":"Noun","tt":"İsim","de":"A water bird with short legs and a flat beak","dt":"Kısa bacaklı ve düz gagalı bir su kuşu","e1":"The ducks are swimming in the lake.","e1t":"Ördekler gölde yüzüyorlar.","e2":"Feed the ducks some bread.","e2t":"Ördeklere biraz ekmek ver."},{"w":"each","tr":"her biri","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"Every one of two or more people or things","dt":"İki veya daha fazla kişiden/şeyden her biri","e1":"Each student has a book.","e1t":"Her öğrencinin bir kitabı var.","e2":"Read each sentence carefully.","e2t":"Her bir cümleyi dikkatlice oku."},{"w":"ear","tr":"kulak","te":"Noun","tt":"İsim","de":"The part of the body used for hearing","dt":"Vücudun duymak için kullanılan kısmı","e1":"We have two ears.","e1t":"İki kulağımız var.","e2":"I am listening with my ears.","e2t":"Kulaklarımla dinliyorum."},{"w":"early","tr":"erken","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Before the usual or expected time","dt":"Olağan veya beklenen zamandan önce","e1":"I wake up early every day.","e1t":"Her gün erken uyanırım.","e2":"The train arrived early.","e2t":"Tren erken vardı."},{"w":"earth","tr":"dünya / toprak","te":"Noun","tt":"İsim","de":"The planet we live on or the ground","dt":"Üzerinde yaşadığımız gezegen veya yer/toprak","e1":"The Earth goes around the sun.","e1t":"Dünya güneşin etrafında döner.","e2":"The earth is very dry.","e2t":"Toprak çok kuru."},{"w":"earthworm","tr":"yer solucanı","te":"Noun","tt":"İsim","de":"A long thin animal that lives in the soil","dt":"Toprakta yaşayan uzun ince hayvan","e1":"Earthworms are good for the garden.","e1t":"Yer solucanları bahçe için iyidir.","e2":"Small earthworm.","e2t":"Küçük solucan."},{"w":"easel","tr":"şövale","te":"Noun","tt":"İsim","de":"A wooden frame for holding an artist's painting","dt":"Sanatçının resmini tutan ahşap çerçeve","e1":"Put the painting on the easel.","e1t":"Resmi şövaleye koy.","e2":"Artist's easel.","e2t":"Sanatçı şövalesi."},{"w":"east","tr":"doğu","te":"Noun","tt":"İsim","de":"The direction where the sun rises","dt":"Güneşin doğduğu yön","e1":"Japan is in the east.","e1t":"Japonya doğudadır.","e2":"The sun rises in the east.","e2t":"Güneş doğudan doğar."},{"w":"easy","tr":"kolay","te":"Adjective","tt":"Sıfat","de":"Achieved without great effort","dt":"Büyük bir çaba sarf etmeden başarılan","e1":"This English test is very easy.","e1t":"Bu İngilizce testi çok kolay.","e2":"It is an easy question.","e2t":"Bu kolay bir soru."},{"w":"eat","tr":"yemek","te":"Verb","tt":"Fiil","de":"To put food into the mouth and swallow it","dt":"Ağza yiyecek koymak ve yutmak","e1":"I eat an apple every day.","e1t":"Her gün bir elma yerim.","e2":"What do you want to eat?","e2t":"Ne yemek istersin?"},{"w":"egg","tr":"yumurta","te":"Noun","tt":"İsim","de":"An oval object produced by a female bird","dt":"Dişi bir kuş tarafından üretilen oval nesne","e1":"I eat two eggs for breakfast.","e1t":"Kahvaltıda iki yumurta yerim.","e2":"Boil the egg for five minutes.","e2t":"Yumurtayı beş dakika haşla."},{"w":"eggplant","tr":"patlıcan","te":"Noun","tt":"İsim","de":"A purple vegetable","dt":"Mor renkli sebze","e1":"I like fried eggplant.","e1t":"Patlıcan kızartmasını severim.","e2":"Big eggplant.","e2t":"Büyük patlıcan."},{"w":"elf","tr":"elf / peri","te":"Noun","tt":"İsim","de":"A small imaginary person with pointed ears","dt":"Sivri kulaklı hayali küçük kişi","e1":"Santa's elves.","e1t":"Noel Baba'nın elfleri.","e2":"(Plural: elves).","e2t":""},{"w":"email","tr":"e","te":"posta","tt":"Noun","de":"İsim","dt":"A message sent through the internet","e1":"İnternet üzerinden gönderilen mesaj","e1t":"Send me an email tomorrow.","e2":"Yarın bana bir e","e2t":"posta gönder."},{"w":"enough","tr":"yeterli","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"As much as is necessary","dt":"Gerektiği kadar","e1":"Do we have enough water?","e1t":"Yeterli suyumuz var mı?","e2":"This room is big enough.","e2t":"Bu oda yeterince büyük."},{"w":"eraser","tr":"silgi","te":"Noun","tt":"İsim","de":"A small piece of rubber used to remove pencil marks","dt":"Kalem izlerini silmek için kullanılan küçük kauçuk parçası","e1":"I need an eraser to fix my mistake.","e1t":"Hatamı düzeltmek için bir silgiye ihtiyacım var.","e2":"Where is my eraser?","e2t":"Silgim nerede?"},{"w":"evening","tr":"akşam","te":"Noun","tt":"İsim","de":"The part of the day between afternoon and night","dt":"Günün öğleden sonrası ile gece arasındaki bölümü","e1":"What are you doing this evening?","e1t":"Bu akşam ne yapıyorsun?","e2":"We watch TV in the evening.","e2t":"Akşamları TV izleriz."},{"w":"exam","tr":"sınav","te":"Noun","tt":"İsim","de":"A formal test of a person's knowledge","dt":"Bir kişinin bilgisinin resmi testi","e1":"The English exam was easy.","e1t":"İngilizce sınavı kolaydı.","e2":"I am studying for my final exam.","e2t":"Final sınavım için çalışıyorum."},{"w":"eye","tr":"göz","te":"Noun","tt":"İsim","de":"The part of the body used for seeing","dt":"Vücudun görmek için kullanılan kısmı","e1":"Close your eyes and sleep.","e1t":"Gözlerini kapat ve uyu.","e2":"She has green eyes.","e2t":"Onun yeşil gözleri var."},{"w":"face","tr":"yüz","te":"Noun","tt":"İsim","de":"The front part of the head","dt":"Başın ön kısmı","e1":"Wash your face, please.","e1t":"Lütfen yüzünü yıka.","e2":"She has a beautiful face.","e2t":"Güzel bir yüzü var."},{"w":"fact","tr":"gerçek","te":"Noun","tt":"İsim","de":"A thing that is known to be true","dt":"Doğru olduğu bilinen şey","e1":"It is a fact that the earth is round.","e1t":"Dünyanın yuvarlak olduğu bir gerçektir.","e2":"Tell me the facts.","e2t":"Bana gerçekleri anlat."},{"w":"fairy","tr":"peri","te":"Noun","tt":"İsim","de":"A small imaginary being with wings and magic","dt":"Kanatlı ve sihirli hayali varlık","e1":"A tooth fairy.","e1t":"Diş perisi.","e2":"Fairy tale.","e2t":"Peri masalı."},{"w":"fall","tr":"sonbahar (ABD)","te":"Noun","tt":"İsim","de":"Another word for autumn","dt":"Sonbahar kelimesinin (ABD) karşılığı","e1":"Leaves fall in the fall.","e1t":"Sonbaharda yapraklar düşer.","e2":"It is cool in the fall.","e2t":"Sonbaharda hava serindir."},{"w":"family","tr":"aile","te":"Noun","tt":"İsim","de":"A group of people who are related","dt":"Akraba olan bir grup insan","e1":"I love my family.","e1t":"Ailemi seviyorum.","e2":"We are a large family.","e2t":"Biz kalabalık bir aileyiz."},{"w":"far","tr":"uzak","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"At a great distance","dt":"Büyük bir mesafede","e1":"The station is far from here.","e1t":"İstasyon buradan uzak.","e2":"How far is the airport?","e2t":"Havaalanı ne kadar uzak?"},{"w":"farmer","tr":"çiftçi","te":"Noun","tt":"İsim","de":"A person who owns or manages a farm","dt":"Çiftlik sahibi olan veya yöneten kişi","e1":"The farmer is milking the cows.","e1t":"Çiftçi inekleri sağıyor.","e2":"My grandfather was a farmer.","e2t":"Büyükbabam bir çiftçiydi."},{"w":"fast","tr":"hızlı","te":"Adjective","tt":"Sıfat","de":"Moving or capable of moving at high speed","dt":"Yüksek hızda hareket eden veya edebilen","e1":"He drives a fast car.","e1t":"Hızlı bir araba sürüyor.","e2":"You speak very fast.","e2t":"Çok hızlı konuşuyorsun."},{"w":"father","tr":"baba","te":"Noun","tt":"İsim","de":"A male parent","dt":"Erkek ebeveyn","e1":"My father is a doctor.","e1t":"Babam bir doktordur.","e2":"He looks like his father.","e2t":"Babasına benziyor."},{"w":"february","tr":"Şubat","te":"Noun","tt":"İsim","de":"The second month of the year","dt":"Yılın ikinci ayı","e1":"February has 28 or 29 days.","e1t":"Şubat 28 veya 29 gündür.","e2":"We go skiing in February.","e2t":"Şubatta kayağa gideriz."},{"w":"feel","tr":"hissetmek","te":"Verb","tt":"Fiil","de":"To experience an emotion or physical sensation","dt":"Bir duyguyu veya fiziksel duyumu tecrübe etmek","e1":"I feel happy today.","e1t":"Bugün mutlu hissediyorum.","e2":"How do you feel?","e2t":"Nasıl hissediyorsun?"},{"w":"few","tr":"az (sayılarla)","te":"Determiner/Adjective","tt":"Belirleyici/Sıfat","de":"A small number of things","dt":"Az sayıda şey (sayılabilenler için)","e1":"I have a few friends in London.","e1t":"Londra'da birkaç arkadaşım var.","e2":"There are few people in the park.","e2t":"Parkta az insan var."},{"w":"film","tr":"film","te":"Noun","tt":"İsim","de":"Another word for movie","dt":"Film kelimesinin bir diğer karşılığı","e1":"This film is very long.","e1t":"Bu film çok uzun.","e2":"I like documentary films.","e2t":"Belgesel filmleri severim."},{"w":"finger","tr":"parmak","te":"Noun","tt":"İsim","de":"One of the five parts at the end of the hand","dt":"Elin ucundaki beş parçadan biri","e1":"I have five fingers on each hand.","e1t":"Her elimde beş parmak var.","e2":"Don't point your finger at me.","e2t":"Parmağını bana doğrultma."},{"w":"finish","tr":"bitirmek","te":"Verb","tt":"Fiil","de":"To bring something to an end","dt":"Bir şeyi sona erdirmek","e1":"I finish my homework early.","e1t":"Ödevimi erken bitiririm.","e2":"Did you finish your meal?","e2t":"Yemeğini bitirdin mi?"},{"w":"fire","tr":"ateş","te":"Noun","tt":"İsim","de":"Heat and light from burning something","dt":"Bir şeyi yakmaktan kaynaklanan ısı ve ışık","e1":"Don't play with fire.","e1t":"Ateşle oynama.","e2":"There is a big fire in the forest.","e2t":"Ormanda büyük bir yangın (ateş) var."},{"w":"first","tr":"birinci","te":"Ordinal Number","tt":"Sıra Numarası","de":"Coming before all others in time or order","dt":"Zaman veya sıra bakımından hepsinden önce gelen","e1":"This is my first car.","e1t":"Bu benim ilk arabam.","e2":"The first lesson is English.","e2t":"İlk ders İngilizce."},{"w":"fish","tr":"balık","te":"Noun","tt":"İsim","de":"An animal that lives and breathes in water","dt":"Suda yaşayan ve nefes alan bir hayvan","e1":"Do you like eating fish?","e1t":"Balık yemeyi sever misin?","e2":"There are many fish in the sea.","e2t":"Denizde çok balık var."},{"w":"flamingo","tr":"flamingo","te":"Noun","tt":"İsim","de":"A large pink bird with long legs","dt":"Uzun bacaklı büyük pembe kuş","e1":"The flamingos are in the lake.","e1t":"Flamingolar göldeler.","e2":"Pink flamingo.","e2t":"Pembe flamingo."},{"w":"flashlight","tr":"el feneri","te":"Noun","tt":"İsim","de":"A small electric light you carry in your hand","dt":"Elinde taşıdığın küçük elektrikli ışık","e1":"Use a flashlight in the dark.","e1t":"Karanlıkta el feneri kullan.","e2":"Bright flashlight.","e2t":"Parlak el feneri."},{"w":"flipper","tr":"yüzgeç","te":"Noun","tt":"İsim","de":"A flat part of a sea animal used for swimming","dt":"Deniz hayvanlarının yüzmek için kullandığı yassı parça","e1":"The seal has flippers.","e1t":"Fokun yüzgeçleri var.","e2":"Swimming flippers.","e2t":"Deniz paleti."},{"w":"floor","tr":"zemin","te":"Noun","tt":"İsim","de":"The surface of a room that you walk on","dt":"Bir odanın üzerinde yürüdüğünüz yüzeyi","e1":"Don't sit on the cold floor.","e1t":"Soğuk zemine oturma.","e2":"The kitchen floor is clean.","e2t":"Mutfak zemini temiz."},{"w":"flute","tr":"flüt","te":"Noun","tt":"İsim","de":"A thin musical instrument that you blow into","dt":"Üflemeli, ince müzik aleti","e1":"She plays the flute well.","e1t":"O iyi flüt çalıyor.","e2":"Silver flute.","e2t":"Gümüş flüt."},{"w":"food","tr":"yiyecek","te":"Noun","tt":"İsim","de":"Things that people and animals eat to live","dt":"İnsanların ve hayvanların yaşamak için yediği şeyler","e1":"Italian food is very popular.","e1t":"İtalyan yiyecekleri çok popülerdir.","e2":"Where is the cat food?","e2t":"Kedi maması (yiyeceği) nerede?"},{"w":"foot","tr":"ayak","te":"Noun","tt":"İsim","de":"The part of the body at the end of the leg","dt":"Vücudun bacağın ucundaki kısmı","e1":"My feet are tired.","e1t":"Ayaklarım yorgun.","e2":"Put your left foot here.","e2t":"Sol ayağını buraya koy."},{"w":"football","tr":"futbol","te":"Noun","tt":"İsim","de":"A game played by two teams with a ball","dt":"İki takım arasında topla oynanan oyun","e1":"We play football every weekend.","e1t":"Her hafta sonu futbol oynuyoruz.","e2":"He is a famous football player.","e2t":"O ünlü bir futbol oyuncusu."},{"w":"for","tr":"için","te":"Preposition","tt":"Edat","de":"Intended to be given to or used by","dt":"Birine verilmesi veya kullanılması amaçlanan","e1":"This gift is for you.","e1t":"Bu hediye senin için.","e2":"I am waiting for the bus.","e2t":"Otobüsü bekliyorum."},{"w":"forest","tr":"orman","te":"Noun","tt":"İsim","de":"A large area with many trees","dt":"Çok sayıda ağacın olduğu büyük alan","e1":"Wild animals live in the forest.","e1t":"Vahşi hayvanlar ormanda yaşar.","e2":"Don't get lost in the forest.","e2t":"Ormanda kaybolma."},{"w":"forget","tr":"unutmak","te":"Verb","tt":"Fiil","de":"To fail to remember something","dt":"Bir şeyi hatırlayamamak","e1":"Don't forget your umbrella.","e1t":"Şemsiyeni unutma.","e2":"I always forget his phone number.","e2t":"Onun telefon numarasını her zaman unuturum."},{"w":"fork","tr":"çatal","te":"Noun","tt":"İsim","de":"A tool with prongs used for picking up food","dt":"Yiyecekleri kaldırmak/tutmak için kullanılan çatallı alet","e1":"Eat your salad with a fork.","e1t":"Salatanı çatalla ye.","e2":"Where are the forks and knives?","e2t":"Çatallar ve bıçaklar nerede?"},{"w":"friday","tr":"Cuma","te":"Noun","tt":"İsim","de":"The last day of the work week","dt":"Çalışma haftasının son günü","e1":"I love Fridays.","e1t":"Cumaları severim.","e2":"Let's meet on Friday evening.","e2t":"Cuma akşamı buluşalım."},{"w":"friend","tr":"arkadaş","te":"Noun","tt":"İsim","de":"A person you know well and like","dt":"İyi tanıdığınız ve sevdiğiniz kişi","e1":"He is my best friend.","e1t":"O benim en iyi arkadaşım.","e2":"We are going out with friends.","e2t":"Arkadaşlarımızla dışarı çıkıyoruz."},{"w":"from","tr":"...den / ...dan","te":"Preposition","tt":"Edat","de":"Indicating the point of origin","dt":"Başlangıç noktasını belirten","e1":"I am from Turkey.","e1t":"Türkiyeli'yim (Türkiye'denim).","e2":"This letter is from my friend.","e2t":"Bu mektup arkadaşımdan."},{"w":"fruit","tr":"meyve","te":"Noun","tt":"İsim","de":"The sweet and fleshy product of a tree or plant","dt":"Bir ağaç veya bitkinin tatlı ve etli ürünü","e1":"Fresh fruit is very healthy.","e1t":"Taze meyve çok sağlıklıdır.","e2":"What is your favorite fruit?","e2t":"En sevdiğin meyve nedir?"},{"w":"game","tr":"oyun","te":"Noun","tt":"İsim","de":"An activity that you do for fun","dt":"Eğlence için yapılan aktivite","e1":"Let's play a video game.","e1t":"Hadi bir video oyunu oynayalım.","e2":"This is a very difficult game.","e2t":"Bu çok zor bir oyun."},{"w":"garden","tr":"bahçe","te":"Noun","tt":"İsim","de":"A piece of land next to a house for growing plants","dt":"Bitki yetiştirmek için bir evin yanındaki arazi","e1":"There are many flowers in the garden.","e1t":"Bahçede çok çiçek var.","e2":"Children are playing in the garden.","e2t":"Çocuklar bahçede oynuyorlar."},{"w":"gift","tr":"hediye","te":"Noun","tt":"İsim","de":"Something given to someone for free","dt":"Birine ücretsiz verilen bir şey","e1":"I bought a gift for my mother.","e1t":"Annem için bir hediye aldım.","e2":"Thank you for the beautiful gift.","e2t":"Bu güzel hediye için teşekkürler."},{"w":"girl","tr":"kız çocuk","te":"Noun","tt":"İsim","de":"A female child","dt":"Kız çocuk","e1":"The little girl is crying.","e1t":"Küçük kız ağlıyor.","e2":"She is a beautiful girl.","e2t":"O güzel bir kız."},{"w":"give","tr":"vermek","te":"Verb","tt":"Fiil","de":"To let someone have something","dt":"Birinin bir şeye sahip olmasına izin vermek","e1":"Give me the book, please.","e1t":"Lütfen kitabı bana ver.","e2":"He gave me a present.","e2t":"Bana bir hediye verdi."},{"w":"gloves","tr":"eldiven","te":"Noun","tt":"İsim","de":"Coverings for the hands","dt":"Eller için örtü/koruyucu","e1":"I wear gloves in winter.","e1t":"Kışın eldiven giyerim.","e2":"My gloves are in my pocket.","e2t":"Eldivenlerim cebimde."},{"w":"go","tr":"gitmek","te":"Verb","tt":"Fiil","de":"To move from one place to another","dt":"Bir yerden başka bir yere hareket etmek","e1":"I go to work by car.","e1t":"İşe arabayla giderim.","e2":"Let's go to the cinema.","e2t":"Hadi sinemaya gidelim."},{"w":"good","tr":"iyi","te":"Adjective","tt":"Sıfat","de":"Of a high quality or standard","dt":"Yüksek kalite veya standartta olan","e1":"This is a very good book.","e1t":"Bu çok iyi bir kitap.","e2":"Have a good time.","e2t":"İyi vakit geçir."},{"w":"goodbye","tr":"hoşça kal","te":"Exclamation","tt":"Ünlem","de":"Used when leaving someone","dt":"Birinden ayrılırken kullanılır","e1":"Goodbye, see you tomorrow.","e1t":"Hoşça kal, yarın görüşürüz.","e2":"It is time to say goodbye.","e2t":"Hoşça kal deme vakti."},{"w":"grape","tr":"üzüm","te":"Noun","tt":"İsim","de":"A small green or purple fruit that grows in bunches","dt":"Salkımlar halinde yetişen küçük yeşil veya mor meyve","e1":"Grapes are used to make juice.","e1t":"Üzümler meyve suyu yapmak için kullanılır.","e2":"He ate a bunch of grapes.","e2t":"Bir salkım üzüm yedi."},{"w":"green","tr":"yeşil","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of grass or leaves","dt":"Çimenlerin veya yaprakların rengi","e1":"The trees are green in spring.","e1t":"İlkbaharda ağaçlar yeşildir.","e2":"Do you like green tea?","e2t":"Yeşil çay sever misin?"},{"w":"grey","tr":"gri","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color between black and white","dt":"Siyah ve beyaz arasındaki renk","e1":"The sky is grey today.","e1t":"Bugün gökyüzü gri (bulutlu).","e2":"He has grey hair.","e2t":"Onun gri (kır) saçları var."},{"w":"hair","tr":"saç","te":"Noun","tt":"İsim","de":"The mass of long threads on the head","dt":"Baş üzerindeki uzun iplikçikler yığını","e1":"She has long blonde hair.","e1t":"Onun uzun sarı saçları var.","e2":"I need a haircut.","e2t":"Saç kesimine ihtiyacım var."},{"w":"hammock","tr":"hamak","te":"Noun","tt":"İsim","de":"A bed made of net or cloth hung between two trees","dt":"İki ağaç arasına asılan ağ veya kumaş yatak","e1":"I am sleeping in a hammock.","e1t":"Hamakta uyuyorum.","e2":"Garden hammock.","e2t":"Bahçe hamağı."},{"w":"hamster","tr":"hamster","te":"Noun","tt":"İsim","de":"A small pet animal like a mouse","dt":"Fareye benzeyen küçük evcil hayvan","e1":"I have a pet hamster.","e1t":"Evcil bir hamsterım var.","e2":"Small hamster.","e2t":"Küçük hamster."},{"w":"hand","tr":"el","te":"Noun","tt":"İsim","de":"The part of the body at the end of the arm","dt":"Vücudun kolun ucundaki kısmı","e1":"Wash your hands before eating.","e1t":"Yemekten önce ellerini yıka.","e2":"Give me your hand.","e2t":"Elini bana ver."},{"w":"happy","tr":"mutlu","te":"Adjective","tt":"Sıfat","de":"Feeling or showing pleasure","dt":"Zevk/memnuniyet hisseden veya gösteren","e1":"I am very happy today.","e1t":"Bugün çok mutluyum.","e2":"They have a happy family.","e2t":"Mutlu bir aileleri var."},{"w":"hard","tr":"zor","te":"Adjective","tt":"Sıfat","de":"Difficult to understand or do","dt":"Anlaması veya yapması güç","e1":"This is a hard problem.","e1t":"Bu zor bir problem.","e2":"Learning a language is hard.","e2t":"Bir dil öğrenmek zordur."},{"w":"hat","tr":"şapka","te":"Noun","tt":"İsim","de":"A covering for the head","dt":"Baş için örtü","e1":"He is wearing a black hat.","e1t":"Siyah bir şapka takıyor.","e2":"Take off your hat inside.","e2t":"İçerideyken şapkanı çıkar."},{"w":"hate","tr":"nefret etmek","te":"Verb","tt":"Fiil","de":"To dislike someone or something very much","dt":"Birinden veya bir şeyden çok fazla hoşlanmamak","e1":"I hate cold weather.","e1t":"Soğuk havadan nefret ederim.","e2":"Why do you hate spiders?","e2t":"Örümceklerden neden nefret ediyorsun?"},{"w":"hazelnut","tr":"fındık","te":"Noun","tt":"İsim","de":"A small brown nut","dt":"Küçük kahverengi kuruyemiş","e1":"Turkey produces many hazelnuts.","e1t":"Türkiye çok fazla fındık üretir.","e2":"A bag of hazelnuts.","e2t":"Bir torba fındık."},{"w":"head","tr":"baş","te":"Noun","tt":"İsim","de":"The part of the body above the neck","dt":"Vücudun boyun üzerindeki kısmı","e1":"He has a large head.","e1t":"Onun büyük bir başı var.","e2":"I have a headache.","e2t":"Başım ağrıyor (baş ağrım var)."},{"w":"health","tr":"sağlık","te":"Noun","tt":"İsim","de":"The state of being free from illness","dt":"Hastalıktan ari olma durumu","e1":"Smoking is bad for your health.","e1t":"Sigara içmek sağlığınız için kötüdür.","e2":"Health is more important than money.","e2t":"Sağlık paradan daha önemlidir."},{"w":"hear","tr":"duymak","te":"Verb","tt":"Fiil","de":"To become aware of a sound using your ears","dt":"Kulaklarını kullanarak bir sesin farkına varmak","e1":"Can you hear me?","e1t":"Beni duyabiliyor musun?","e2":"I heard a strange noise.","e2t":"Garip bir ses duydum."},{"w":"heart","tr":"kalp","te":"Noun","tt":"İsim","de":"The organ that pumps blood","dt":"Kan pompalayan organ","e1":"My heart is beating fast.","e1t":"Kalbim hızlı çarpıyor.","e2":"He has a kind heart.","e2t":"Nazik bir kalbi var."},{"w":"hedgehog","tr":"kirpi","te":"Noun","tt":"İsim","de":"A small animal covered in sharp spikes","dt":"Keskin dikenlerle kaplı küçük hayvan","e1":"The hedgehog is in the garden.","e1t":"Kirpi bahçede.","e2":"Small hedgehog.","e2t":"Küçük kirpi."},{"w":"hello","tr":"merhaba","te":"Exclamation","tt":"Ünlem","de":"Used as a greeting","dt":"Selamlama olarak kullanılır","e1":"Hello, how are you?","e1t":"Merhaba, nasılsın?","e2":"Say hello to your father.","e2t":"Babana merhaba de."},{"w":"help","tr":"yardım etmek","te":"Verb","tt":"Fiil","de":"To make it easier for someone to do something","dt":"Birinin bir şeyi yapmasını kolaylaştırmak","e1":"Can you help me, please?","e1t":"Lütfen bana yardım edebilir misin?","e2":"I help my mother in the kitchen.","e2t":"Anneme mutfakta yardım ederim."},{"w":"her satır bir kelime paketidir. programında `","tr":"` (dik çizgi) karakterini ayraç olarak kullanarak verileri çekebilirsin. İlk 50 kelimelik partiyi aşağıda sunuyorum:","te":"undefined","tt":"undefined","de":"undefined","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"hippo","tr":"hipopotam / su aygırı","te":"Noun","tt":"İsim","de":"Short for hippopotamus; a large water animal","dt":"Su aygırının kısaltması; büyük su hayvanı","e1":"The hippo is in the river.","e1t":"Hipopotam nehirde.","e2":"Fat hippo.","e2t":"Şişman hipopotam."},{"w":"hippopotamus","tr":"su aygırı / hipopotam","te":"Noun","tt":"İsim","de":"A very large animal that lives near African rivers","dt":"Afrika nehirleri kenarında yaşayan çok büyük hayvan","e1":"The hippopotamus is in the water.","e1t":"Su aygırı suyun içinde.","e2":"Big hippo.","e2t":"Büyük su aygırı."},{"w":"holiday","tr":"tatil","te":"Noun","tt":"İsim","de":"A period of time when you do not work","dt":"Çalışmadığınız zaman dilimi","e1":"I am going on holiday next week.","e1t":"Gelecek hafta tatile gidiyorum.","e2":"Where did you go for holiday?","e2t":"Tatil için nereye gittin?"},{"w":"horse","tr":"at","te":"Noun","tt":"İsim","de":"A large animal used for riding or pulling loads","dt":"Binmek veya yük çekmek için kullanılan büyük hayvan","e1":"He can ride a horse.","e1t":"At binebilir.","e2":"The horse is running fast.","e2t":"At hızlı koşuyor."},{"w":"hose","tr":"hortum","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flexible tube for moving water","dt":"Su taşımak için esnek boru","e1":"A garden hose.","e1t":"Bahçe hortumu.","e2":"Water the garden with a hose.","e2t":"Bahçeyi hortumla sula."},{"w":"hospital","tr":"hastane","te":"Noun","tt":"İsim","de":"A place where sick people are treated","dt":"Hasta insanların tedavi edildiği yer","e1":"He is in the hospital now.","e1t":"O şu an hastanede.","e2":"Where is the nearest hospital?","e2t":"En yakın hastane nerede?"},{"w":"hot","tr":"sıcak","te":"Adjective","tt":"Sıfat","de":"Having a high temperature","dt":"Yüksek sıcaklığa sahip olma","e1":"The weather is very hot today.","e1t":"Bugün hava çok sıcak.","e2":"Be careful, the tea is hot.","e2t":"Dikkatli ol, çay sıcak."},{"w":"hour","tr":"saat (süre)","te":"Noun","tt":"İsim","de":"A period of time equal to sixty minutes","dt":"Altmış dakikalık zaman dilimi","e1":"I wait for an hour.","e1t":"Bir saattir bekliyorum.","e2":"Two hours later.","e2t":"İki saat sonra."},{"w":"house","tr":"ev","te":"Noun","tt":"İsim","de":"A building where people live","dt":"İnsanların yaşadığı bina","e1":"My house is near the park.","e1t":"Evim parkın yakınında.","e2":"They are building a new house.","e2t":"Yeni bir ev inşa ediyorlar."},{"w":"how","tr":"nasıl","te":"Adverb","tt":"Zarf","de":"In what way or manner","dt":"Hangi şekilde veya tarzda","e1":"How do you go to school?","e1t":"Okula nasıl gidersin?","e2":"How was your day?","e2t":"Günün nasıldı?"},{"w":"hungry","tr":"aç","te":"Adjective","tt":"Sıfat","de":"Feeling a need to eat food","dt":"Yemek yeme ihtiyacı hissetme","e1":"I am hungry, let's eat something.","e1t":"Açım, hadi bir şeyler yiyelim.","e2":"The cat is very hungry.","e2t":"Kedi çok aç."},{"w":"husband","tr":"koca","te":"Noun","tt":"İsim","de":"The man that a woman is married to","dt":"Bir kadının evli olduğu adam","e1":"Her husband works in a bank.","e1t":"Kocası bir bankada çalışıyor.","e2":"He is a loving husband.","e2t":"O sevgi dolu bir koca."},{"w":"idea","tr":"fikir","te":"Noun","tt":"İsim","de":"A thought or suggestion","dt":"Düşünce veya öneri","e1":"I have a great idea!","e1t":"Harika bir fikrim var!","e2":"That is a good idea.","e2t":"Bu iyi bir fikir."},{"w":"if","tr":"eğer","te":"Conjunction","tt":"Bağlaç","de":"On the condition that","dt":"... koşuluyla","e1":"If it rains, we will stay home.","e1t":"Eğer yağmur yağarsa evde kalacağız.","e2":"Tell me if you need help.","e2t":"Yardıma ihtiyacın olursa bana söyle."},{"w":"igloo","tr":"iglo / buzdan ev","te":"Noun","tt":"İsim","de":"A house made of snow blocks","dt":"Kar bloklarından yapılan ev","e1":"Eskimos live in igloos.","e1t":"Eskimolar iglolarda yaşar.","e2":"Cold igloo.","e2t":"Soğuk iglo."},{"w":"in","tr":"içinde","te":"Preposition","tt":"Edat","de":"Inside a place or period of time","dt":"Bir yerin veya zaman diliminin içinde","e1":"The keys are in my bag.","e1t":"Anahtarlar çantamın içinde.","e2":"I was born in 1990.","e2t":"1990'da doğdum."},{"w":"inside","tr":"içinde","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Within or towards the interior","dt":"İçinde veya iç kısma doğru","e1":"Go inside the house.","e1t":"Evin içine gir.","e2":"What is inside the box?","e2t":"Kutunun içinde ne var?"},{"w":"internet","tr":"internet","te":"Noun","tt":"İsim","de":"A global computer network","dt":"Küresel bilgisayar ağı","e1":"I use the internet to learn English.","e1t":"İngilizce öğrenmek için interneti kullanırım.","e2":"Is there internet in the hotel?","e2t":"Otelde internet var mı?"},{"w":"into","tr":"içine","te":"Preposition","tt":"Edat","de":"To the inside","dt":"İç tarafa doğru","e1":"Come into the house.","e1t":"Evin içine gel.","e2":"Put it into the box.","e2t":"Onu kutunun içine koy."},{"w":"island","tr":"ada","te":"Noun","tt":"İsim","de":"A piece of land surrounded by water","dt":"Etrafı suyla çevrili kara parçası","e1":"We went to a beautiful island.","e1t":"Güzel bir adaya gittik.","e2":"Is this a private island?","e2t":"Bu özel bir ada mı?"},{"w":"issue","tr":"mesele","te":"Noun","tt":"İsim","de":"An important topic or problem","dt":"Önemli bir konu veya sorun","e1":"This is a very sensitive issue.","e1t":"Bu çok hassas bir mesele.","e2":"We need to discuss this issue.","e2t":"Bu meseleyi tartışmamız gerekiyor."},{"w":"jacket","tr":"ceket","te":"Noun","tt":"İsim","de":"A short coat","dt":"Kısa palto/ceket","e1":"It's cold, wear your jacket.","e1t":"Hava soğuk, ceketini giy.","e2":"This is a leather jacket.","e2t":"Bu deri bir ceket."},{"w":"january","tr":"Ocak","te":"Noun","tt":"İsim","de":"The first month of the year","dt":"Yılın ilk ayı","e1":"It is cold in January.","e1t":"Ocak ayında hava soğuktur.","e2":"My birthday is in January.","e2t":"Doğum günüm Ocak ayında."},{"w":"jellyfish","tr":"denizanası","te":"Noun","tt":"İsim","de":"A soft sea animal that can sting","dt":"Sokabilen, yumuşak deniz canlısı","e1":"Be careful of the jellyfish!","e1t":"Denizanasına dikkat et!","e2":"Clear jellyfish.","e2t":"Şeffaf denizanası."},{"w":"job","tr":"iş","te":"Noun","tt":"İsim","de":"The work that a person does to earn money","dt":"Bir kişinin para kazanmak için yaptığı iş","e1":"I am looking for a new job.","e1t":"Yeni bir iş arıyorum.","e2":"What is your father's job?","e2t":"Babanın işi (mesleği) ne?"},{"w":"juice","tr":"meyve suyu","te":"Noun","tt":"İsim","de":"The liquid that comes from fruit or vegetables","dt":"Meyve veya sebzelerden gelen sıvı","e1":"I want a glass of apple juice.","e1t":"Bir bardak elma suyu istiyorum.","e2":"Is this fresh orange juice?","e2t":"Bu taze portakal suyu mu?"},{"w":"july","tr":"Temmuz","te":"Noun","tt":"İsim","de":"The seventh month of the year","dt":"Yılın yedinci ayı","e1":"July is very hot.","e1t":"Temmuz ayı çok sıcaktır.","e2":"We go on vacation in July.","e2t":"Temmuzda tatile gideriz."},{"w":"jump","tr":"zıplamak","te":"Verb","tt":"Fiil","de":"To push oneself off the ground into the air","dt":"Kendini yerden havaya doğru itmek","e1":"Can you jump over the wall?","e1t":"Duvarın üzerinden atlayabilir misin?","e2":"The kids are jumping on the bed.","e2t":"Çocuklar yatakta zıplıyorlar."},{"w":"june","tr":"Haziran","te":"Noun","tt":"İsim","de":"The sixth month of the year","dt":"Yılın altıncı ayı","e1":"Summer starts in June.","e1t":"Yaz Haziranda başlar.","e2":"Schools close in June.","e2t":"Okullar Haziranda kapanır."},{"w":"just","tr":"sadece / henüz","te":"Adverb","tt":"Zarf","de":"Simply or a very short time ago","dt":"Basitçe veya çok kısa süre önce","e1":"I am just looking.","e1t":"Sadece bakıyorum.","e2":"I have just arrived.","e2t":"Henüz vardım."},{"w":"keyboard","tr":"klavye","te":"Noun","tt":"İsim","de":"A set of keys used to type on a computer","dt":"Bilgisayarda yazı yazmak için kullanılan tuş takımı","e1":"I need a new keyboard.","e1t":"Yeni bir klavyeye ihtiyacım var.","e2":"Don't spill water on the keyboard.","e2t":"Klavyenin üzerine su dökme."},{"w":"kitchen","tr":"mutfak","te":"Noun","tt":"İsim","de":"A room where food is kept, prepared, and cooked","dt":"Yiyeceklerin saklandığı, hazırlandığı ve pişirildiği oda","e1":"My mother is in the kitchen.","e1t":"Annem mutfakta.","e2":"We have a small kitchen.","e2t":"Küçük bir mutfağımız var."},{"w":"kiwi","tr":"kivi","te":"Noun","tt":"İsim","de":"A small fruit with brown fuzzy skin and green flesh","dt":"Kahverengi tüylü kabuklu ve yeşil etli küçük meyve","e1":"I like kiwi juice.","e1t":"Kivi suyunu severim.","e2":"Green kiwi.","e2t":"Yeşil kivi."},{"w":"knife","tr":"bıçak","te":"Noun","tt":"İsim","de":"A tool with a sharp blade used for cutting","dt":"Kesmek için kullanılan keskin bıçaklı bir alet","e1":"Use a sharp knife to cut meat.","e1t":"Eti kesmek için keskin bir bıçak kullan.","e2":"Be careful, the knife is sharp.","e2t":"Dikkatli ol, bıçak keskin."},{"w":"know","tr":"bilmek","te":"Verb","tt":"Fiil","de":"To have information about something in your mind","dt":"Zihninde bir şeyle ilgili bilgiye sahip olmak","e1":"I know the answer.","e1t":"Cevabı biliyorum.","e2":"Do you know his name?","e2t":"Onun ismini biliyor musun?"},{"w":"koala","tr":"koala","te":"Noun","tt":"İsim","de":"An Australian animal that lives in trees","dt":"Ağaçlarda yaşayan Avustralya hayvanı","e1":"The koala is sleeping.","e1t":"Koala uyuyor.","e2":"Cute koala.","e2t":"Sevimli koala."},{"w":"ladybug","tr":"uğur böceği","te":"Noun","tt":"İsim","de":"A small red beetle with black spots","dt":"Siyah noktalı küçük kırmızı böcek","e1":"I found a ladybug.","e1t":"Bir uğur böceği buldum.","e2":"Red ladybug.","e2t":"Kırmızı uğur böceği."},{"w":"lake","tr":"göl","te":"Noun","tt":"İsim","de":"A large area of water surrounded by land","dt":"Etrafı kara ile çevrili büyük su alanı","e1":"There is a small boat on the lake.","e1t":"Gölün üzerinde küçük bir tekne var.","e2":"Let's have a picnic by the lake.","e2t":"Göl kenarında piknik yapalım."},{"w":"lamp","tr":"lamba","te":"Noun","tt":"İsim","de":"A device that produces light","dt":"Işık üreten bir cihaz","e1":"Turn on the lamp, please.","e1t":"Lütfen lambayı yak.","e2":"There is a lamp on the desk.","e2t":"Masanın üzerinde bir lamba var."},{"w":"laptop","tr":"dizüstü bilgisayar","te":"Noun","tt":"İsim","de":"A small computer that you can carry","dt":"Taşıyabileceğiniz küçük bilgisayar","e1":"Open your laptop and start working.","e1t":"Dizüstü bilgisayarını aç ve çalışmaya baş.","e2":"My laptop is on the desk.","e2t":"Dizüstü bilgisayarım masanın üzerinde."},{"w":"last","tr":"son","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Coming after all others","dt":"Hepsinden sonra gelen","e1":"December is the last month of the year.","e1t":"Aralık yılın son ayıdır.","e2":"Who was the last person to leave?","e2t":"En son ayrılan kişi kimdi?"},{"w":"late","tr":"geç","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"After the expected or usual time","dt":"Beklenen veya olağan zamandan sonra","e1":"Why are you late?","e1t":"Neden geç kaldın?","e2":"Don't stay up late.","e2t":"Geç saatlere kadar oturma."},{"w":"left","tr":"sol","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The side of your body with the heart","dt":"Vücudun kalbin olduğu tarafı","e1":"Turn left at the corner.","e1t":"Köşeden sola dön.","e2":"My house is on the left.","e2t":"Evim solda."},{"w":"leg","tr":"bacak","te":"Noun","tt":"İsim","de":"The part of the body used for standing and walking","dt":"Ayakta durmak ve yürümek için kullanılan vücut bölümü","e1":"These pants are for long legs.","e1t":"Bu pantolon uzun bacaklar içindir.","e2":"My legs are hurting.","e2t":"Bacaklarım ağrıyor."},{"w":"lemon","tr":"limon","te":"Noun","tt":"İsim","de":"A yellow citrus fruit with a sour taste","dt":"Ekşi tadı olan sarı bir narenciye meyvesi","e1":"Add some lemon to the tea.","e1t":"Çaya biraz limon ekle.","e2":"This lemon is very sour.","e2t":"Bu limon çok ekşi."},{"w":"lemonade","tr":"limonata","te":"Noun","tt":"İsim","de":"A drink made from lemons, sugar, and water","dt":"Limon, şeker ve sudan yapılan içecek","e1":"I want a cold lemonade.","e1t":"Soğuk bir limonata istiyorum.","e2":"Sweet lemonade.","e2t":"Tatlı limonata."},{"w":"lesson","tr":"ders","te":"Noun","tt":"İsim","de":"A period of time in which students are taught","dt":"Öğrencilere bir şeyler öğretilen zaman dilimi","e1":"The history lesson starts at 9 AM.","e1t":"Tarih dersi sabah 9'da başlıyor.","e2":"I learned a lot from this lesson.","e2t":"Bu dersten çok şey öğrendim."},{"w":"letter","tr":"harf / mektup","te":"Noun","tt":"İsim","de":"A character of the alphabet or a written message","dt":"Alfabenin bir karakteri veya yazılı mesaj","e1":"'A' is the first letter of the alphabet.","e1t":"'A' alfabenin ilk harfidir.","e2":"I received a letter from my friend.","e2t":"Arkadaşımdan bir mektup aldım."},{"w":"library","tr":"kütüphane","te":"Noun","tt":"İsim","de":"A building containing collections of books","dt":"Kitap koleksiyonları barındıran bina","e1":"You must be quiet in the library.","e1t":"Kütüphanede sessiz olmalısın.","e2":"I borrow books from the library.","e2t":"Kütüphaneden kitap ödünç alırım."},{"w":"lighthouse","tr":"deniz feneri","te":"Noun","tt":"İsim","de":"A tower with a strong light to guide ships","dt":"Gemilere yol gösteren ışıklı kule","e1":"The lighthouse is on the rocks.","e1t":"Deniz feneri kayalıkların üzerinde.","e2":"Bright lighthouse.","e2t":"Parlak deniz feneri."},{"w":"like","tr":"gibi","te":"Preposition","tt":"Edat","de":"Similar to","dt":"Benzer","e1":"He looks like his father.","e1t":"Babasına benziyor (babası gibi görünüyor).","e2":"It tastes like chicken.","e2t":"Tadı tavuk gibi."},{"w":"listen","tr":"dinlemek","te":"Verb","tt":"Fiil","de":"To give attention to a sound","dt":"Bir sese dikkatini vermek","e1":"I like listening to music.","e1t":"Müzik dinlemeyi severim.","e2":"Listen to your teacher.","e2t":"Öğretmenini dinle."},{"w":"little","tr":"az (miktar)","te":"Determiner/Adjective","tt":"Belirleyici/Sıfat","de":"A small amount of something","dt":"Az miktarda şey (sayılamayanlar için)","e1":"Add a little sugar to my coffee.","e1t":"Kahveme biraz (az) şeker ekle.","e2":"I have little time to talk.","e2t":"Konuşmak için az vaktim var."},{"w":"live","tr":"yaşamak","te":"Verb","tt":"Fiil","de":"To have one's home in a particular place","dt":"Belirli bir yerde evine sahip olmak (ikamet etmek)","e1":"I live in Istanbul.","e1t":"İstanbul'da yaşıyorum.","e2":"They live in a small village.","e2t":"Küçük bir köyde yaşıyorlar."},{"w":"living room","tr":"oturma odası","te":"Noun","tt":"İsim","de":"The room in a house where people sit and relax","dt":"Bir evde insanların oturduğu ve dinlendiği oda","e1":"We watch movies in the living room.","e1t":"Oturma odasında film izleriz.","e2":"The sofa is in the living room.","e2t":"Kanepe oturma odasında."},{"w":"lobster","tr":"ıstakoz","te":"Noun","tt":"İsim","de":"A large sea animal with a hard shell and claws","dt":"Sert kabuklu ve kıskaçlı büyük deniz canlısı","e1":"The lobster is red.","e1t":"Istakoz kırmızıdır.","e2":"Big lobster.","e2t":"Büyük ıstakoz."},{"w":"lollipop","tr":"lolipop","te":"Noun","tt":"İsim","de":"Hard candy on a stick","dt":"Çubuk üzerinde sert şekerleme","e1":"The boy has a strawberry lollipop.","e1t":"Çocuğun çilekli bir lolipopu var.","e2":"Sweet lollipop.","e2t":"Tatlı lolipop."},{"w":"long","tr":"uzun","te":"Adjective","tt":"Sıfat","de":"Measuring a great distance from end to end","dt":"Bir uçtan diğer uca büyük bir mesafe ölçen","e1":"This is a long road.","e1t":"Bu uzun bir yol.","e2":"She has long hair.","e2t":"Onun uzun saçları var."},{"w":"look","tr":"bakmak","te":"Verb","tt":"Fiil","de":"To direct one's eyes towards something","dt":"Gözlerini bir şeye doğru yöneltmek","e1":"Look at this picture.","e1t":"Bu resme bak.","e2":"Look left and right.","e2t":"Sola ve sağa bak."},{"w":"lose","tr":"kaybetmek","te":"Verb","tt":"Fiil","de":"To not find or not win","dt":"Bulamamak veya kazanamamak","e1":"Don't lose your keys.","e1t":"Anahtarlarını kaybetme.","e2":"We lost the game.","e2t":"Maçı kaybettik."},{"w":"loud","tr":"gürültülü","te":"Adjective","tt":"Sıfat","de":"Producing a lot of noise","dt":"Çok fazla gürültü çıkaran","e1":"The music is too loud.","e1t":"Müzik çok yüksek sesli (gürültülü).","e2":"I heard a loud noise.","e2t":"Yüksek bir ses duydum."},{"w":"love","tr":"sevmek","te":"Verb","tt":"Fiil","de":"To feel deep affection for someone or something","dt":"Birine veya bir şeye derin sevgi duymak","e1":"I love my family.","e1t":"Ailemi seviyorum.","e2":"She loves chocolate.","e2t":"Çikolataya bayılıyor (seviyor)."},{"w":"lunch","tr":"öğle yemeği","te":"Noun","tt":"İsim","de":"A meal eaten in the middle of the day","dt":"Günün ortasında yenen bir öğün","e1":"Let's have lunch together.","e1t":"Haydi birlikte öğle yemeği yiyelim.","e2":"I have lunch at 12 o'clock.","e2t":"Saat 12'de öğle yemeği yerim."},{"w":"magnifying glass","tr":"büyüteç","te":"Noun","tt":"İsim","de":"A lens that makes things look larger","dt":"Nesneleri daha büyük gösteren mercek","e1":"Use a magnifying glass to see the ant.","e1t":"Karıncayı görmek için büyüteç kullan.","e2":"Small magnifying glass.","e2t":"Küçük büyüteç."},{"w":"mail","tr":"posta","te":"Noun/Verb","tt":"İsim/Fiil","de":"Letters and parcels sent by post","dt":"Posta ile gönderilen mektuplar ve paketler","e1":"Did we get any mail today?","e1t":"Bugün hiç posta aldık mı?","e2":"I will mail the documents tomorrow.","e2t":"Belgeleri yarın postalayacağım."},{"w":"make","tr":"yapmak","te":"Verb","tt":"Fiil","de":"To create or produce something","dt":"Bir şey yaratmak veya üretmek","e1":"I make a cake for the party.","e1t":"Parti için bir kek yapıyorum.","e2":"He makes a lot of mistakes.","e2t":"Çok hata yapıyor."},{"w":"mall","tr":"AVM","te":"Noun","tt":"İsim","de":"A large building with many different shops","dt":"İçinde birçok farklı dükkan olan büyük bina","e1":"Let's go to the mall this weekend.","e1t":"Bu hafta sonu AVM'ye gidelim.","e2":"The mall has a large cinema.","e2t":"AVM'nin büyük bir sineması var."},{"w":"man","tr":"adam","te":"Noun","tt":"İsim","de":"An adult male human","dt":"Yetişkin erkek insan","e1":"He is a tall man.","e1t":"O uzun boylu bir adamdır.","e2":"The man is wearing a suit.","e2t":"Adam takım elbise giyiyor."},{"w":"many","tr":"birçok","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"A large number of (countable)","dt":"Çok sayıda (sayılabilen)","e1":"I have many friends.","e1t":"Birçok arkadaşım var.","e2":"How many books did you read?","e2t":"Kaç tane kitap okudun?"},{"w":"map","tr":"harita","te":"Noun","tt":"İsim","de":"A visual representation of an area","dt":"Bir alanın görsel temsili","e1":"Look at the map to find the street.","e1t":"Sokağı bulmak için haritaya bak.","e2":"Do you have a map of the city?","e2t":"Şehrin haritası var mı?"},{"w":"march","tr":"Mart","te":"Noun","tt":"İsim","de":"The third month of the year","dt":"Yılın üçüncü ayı","e1":"Spring starts in March.","e1t":"Bahar Martta başlar.","e2":"It is often rainy in March.","e2t":"Martta hava sık sık yağmurludur."},{"w":"market","tr":"market","te":"Noun","tt":"İsim","de":"A place where people buy and sell goods","dt":"İnsanların mal alıp sattığı yer","e1":"I buy fresh vegetables from the market.","e1t":"Marketten taze sebze alırım.","e2":"The market is very crowded today.","e2t":"Market bugün çok kalabalık."},{"w":"may","tr":"Mayıs","te":"Noun","tt":"İsim","de":"The fifth month of the year","dt":"Yılın beşinci ayı","e1":"The weather is warm in May.","e1t":"Mayısta hava ılıktır.","e2":"My sister was born in May.","e2t":"Kız kardeşim Mayısta doğdu."},{"w":"meal","tr":"öğün","te":"Noun","tt":"İsim","de":"An occasion when people sit down to eat food","dt":"İnsanların yemek yemek için oturduğu bir durum/vakit","e1":"I eat three meals a day.","e1t":"Günde üç öğün yemek yerim.","e2":"Thank you for this delicious meal.","e2t":"Bu lezzetli öğün için teşekkürler."},{"w":"meat","tr":"et","te":"Noun","tt":"İsim","de":"The flesh of an animal used as food","dt":"Hayvanın yiyecek olarak kullanılan eti","e1":"I don't eat much red meat.","e1t":"Çok fazla kırmızı et yemem.","e2":"Cook the meat slowly.","e2t":"Eti yavaşça pişir."},{"w":"medicine","tr":"ilaç","te":"Noun","tt":"İsim","de":"A substance used to treat an illness","dt":"Bir hastalığı tedavi etmek için kullanılan madde","e1":"Take your medicine after lunch.","e1t":"İlacını öğle yemeğinden sonra al.","e2":"This medicine is for your headache.","e2t":"Bu ilaç baş ağrın için."},{"w":"meeting","tr":"toplantı","te":"Noun","tt":"İsim","de":"An occasion when people come together to discuss something","dt":"İnsanların bir şeyi tartışmak için bir araya geldiği durum","e1":"The meeting starts in ten minutes.","e1t":"Toplantı on dakika içinde başlıyor.","e2":"I have an important meeting today.","e2t":"Bugün önemli bir toplantım var."},{"w":"message","tr":"mesaj","te":"Noun","tt":"İsim","de":"A short piece of information sent to someone","dt":"Birine gönderilen kısa bilgi parçası","e1":"I received a message from my mother.","e1t":"Annemden bir mesaj aldım.","e2":"Leave a message after the beep.","e2t":"Sinyalden sonra mesaj bırakın."},{"w":"milk","tr":"süt","te":"Noun","tt":"İsim","de":"A white liquid produced by cows or goats","dt":"İnekler veya keçiler tarafından üretilen beyaz sıvı","e1":"Babies drink milk to grow.","e1t":"Bebekler büyümek için süt içer.","e2":"Put some milk in your cereal.","e2t":"Gevreğine biraz süt koy."},{"w":"miss","tr":"özlemek / kaçırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel sad without someone; or fail to hit","dt":"Birinin eksikliğini hissetmek; veya ıskalamak","e1":"I miss my family.","e1t":"Ailemi özlüyorum.","e2":"Miss the bus.","e2t":"Otobüsü kaçırmak."},{"w":"mom","tr":"anne","te":"Noun","tt":"İsim","de":"Informal word for mother","dt":"Annenin samimi söylenişi","e1":"My mom is cooking.","e1t":"Annem yemek pişiriyor.","e2":"Best mom.","e2t":"En iyi anne."},{"w":"monday","tr":"Pazartesi","te":"Noun","tt":"İsim","de":"The first day of the work week","dt":"Çalışma haftasının ilk günü","e1":"I go to the gym on Monday.","e1t":"Pazartesi günü spor salonuna giderim.","e2":"Monday is a busy day.","e2t":"Pazartesi yoğun bir gündür."},{"w":"money","tr":"para","te":"Noun","tt":"İsim","de":"Coins or notes used to buy things","dt":"Bir şeyler almak için kullanılan madeni veya kağıt para","e1":"I don't have much money.","e1t":"Çok param yok.","e2":"Time is money.","e2t":"Vakit nakittir (paradır)."},{"w":"month","tr":"ay","te":"Noun","tt":"İsim","de":"One of the twelve periods of a year","dt":"Bir yılın on iki döneminden biri","e1":"February is the shortest month.","e1t":"Şubat en kısa aydır.","e2":"I am going on holiday next month.","e2t":"Gelecek ay tatile gidiyorum."},{"w":"moon","tr":"ay","te":"Noun","tt":"İsim","de":"The natural satellite of the earth","dt":"Dünyanın doğal uydusu","e1":"The moon is very bright tonight.","e1t":"Bu gece ay çok parlak.","e2":"There is no air on the moon.","e2t":"Ayda hava yoktur."},{"w":"moonlight","tr":"ay ışığı","te":"Noun","tt":"İsim","de":"Light from the moon","dt":"Ay'dan gelen ışık","e1":"We walked under the moonlight.","e1t":"Ay ışığı altında yürüdük.","e2":"The moonlight is very romantic.","e2t":"Ay ışığı çok romantik."},{"w":"mop","tr":"paspas / paspaslamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for washing floors","dt":"Yerleri yıkama aracı","e1":"Use a mop to clean the kitchen.","e1t":"Mutfağı temizlemek için paspas kullan.","e2":"Wet mop.","e2t":"Islak paspas."},{"w":"more","tr":"daha fazla","te":"Determiner/Adverb","tt":"A greater amount or number","de":"Daha büyük bir miktar veya sayı","dt":"Can I have more water, please?","e1":"Daha fazla su alabilir miyim lütfen?","e1t":"We need more time.","e2":"Daha fazla zamana ihtiyacımız var.","e2t":""},{"w":"morning","tr":"sabah","te":"Noun","tt":"İsim","de":"The early part of the day","dt":"Günün erken bölümü","e1":"I drink tea every morning.","e1t":"Her sabah çay içerim.","e2":"Good morning, everyone!","e2t":"Günaydın herkese!"},{"w":"most","tr":"en çok","te":"Determiner/Adverb","tt":"The greatest amount or number","de":"En büyük miktar veya sayı","dt":"Most people like chocolate.","e1":"Çoğu insan çikolatayı sever.","e1t":"Who has the most money?","e2":"En çok para kimde?","e2t":""},{"w":"mother","tr":"anne","te":"Noun","tt":"İsim","de":"A female parent","dt":"Kadın ebeveyn","e1":"My mother cooks delicious food.","e1t":"Annem lezzetli yemekler yapar.","e2":"Happy Mother's Day!","e2t":"Anneler Günü kutlu olsun!"},{"w":"mountain","tr":"dağ","te":"Noun","tt":"İsim","de":"A very high hill","dt":"Çok yüksek tepe","e1":"We like climbing mountains.","e1t":"Dağlara tırmanmayı severiz.","e2":"The mountain is covered with snow.","e2t":"Dağ karla kaplı."},{"w":"mouse","tr":"fare","te":"Noun","tt":"İsim","de":"A small device used to control a computer cursor","dt":"Bilgisayar imlecini kontrol eden küçük cihaz","e1":"Move the mouse to the right.","e1t":"Fareyi sağa hareket ettir.","e2":"The computer mouse is broken.","e2t":"Bilgisayar faresi bozuk."},{"w":"mouth","tr":"ağız","te":"Noun","tt":"İsim","de":"The part of the face used for eating and speaking","dt":"Yüzün yemek yemek ve konuşmak için kullanılan kısmı","e1":"Open your mouth, please.","e1t":"Lütfen ağzını aç.","e2":"Don't speak with food in your mouth.","e2t":"Ağzında yemek varken konuşma."},{"w":"movie","tr":"film","te":"Noun","tt":"İsim","de":"A story shown in moving pictures","dt":"Hareketli görüntülerle gösterilen hikaye","e1":"Let's watch a scary movie.","e1t":"Hadi korkunç bir film izleyelim.","e2":"Who is your favorite movie star?","e2t":"En sevdiğin film yıldızı kim?"},{"w":"much","tr":"çok","te":"Determiner/Adverb","tt":"A large amount of (uncountable)","de":"Çok miktarda (sayılamayan)","dt":"How much is this shirt?","e1":"Bu gömlek ne kadar?","e1t":"I don't have much time.","e2":"Çok vaktim yok.","e2t":""},{"w":"mug","tr":"kupa / büyük bardak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large cup with a handle used for hot drinks","dt":"Sıcak içecekler için kullanılan kulplu büyük bardak","e1":"A mug of hot chocolate.","e1t":"Bir kupa sıcak çikolata.","e2":"Coffee mug.","e2t":"Kahve kupası."},{"w":"music","tr":"müzik","te":"Noun","tt":"İsim","de":"Vocal or instrumental sounds combined","dt":"Ses veya enstrüman seslerinin birleşimi","e1":"Listen to some relaxing music.","e1t":"Biraz rahatlatıcı müzik dinle.","e2":"What kind of music do you like?","e2t":"Ne tür müzik seversin?"},{"w":"nature","tr":"doğa","te":"Noun","tt":"İsim","de":"The physical world including plants and animals","dt":"Bitkiler ve hayvanlar dahil fiziksel dünya","e1":"I love spending time in nature.","e1t":"Doğada vakit geçirmeyi seviyorum.","e2":"We must protect nature.","e2t":"Doğayı korumalıyız."},{"w":"near","tr":"yakın","te":"Preposition/Adjective","tt":"At a short distance away","de":"Kısa bir mesafe uzaklıkta","dt":"I live near the school.","e1":"Okula yakın yaşıyorum.","e1t":"Is there a bank near here?","e2":"Buralarda yakınlarda bir banka var mı?","e2t":""},{"w":"neck","tr":"boyun","te":"Noun","tt":"İsim","de":"The part of the body that joins the head to the chest","dt":"Baş ile göğsü birleştiren vücut bölümü","e1":"Wear a scarf to keep your neck warm.","e1t":"Boynunu sıcak tutmak için atkı tak.","e2":"He has a long neck.","e2t":"Onun uzun bir boynu var."},{"w":"necklace","tr":"kolye","te":"Noun","tt":"İsim","de":"A piece of jewelry worn around the neck","dt":"Boyna takılan takı","e1":"She has a beautiful necklace.","e1t":"Onun güzel bir kolyesi var.","e2":"Gold necklace.","e2t":"Altın kolye."},{"w":"need","tr":"ihtiyaç duymak","te":"Verb","tt":"Fiil","de":"To require something because it is essential","dt":"Temel olduğu için bir şeye gereksinim duymak","e1":"I need a new pen.","e1t":"Yeni bir kaleme ihtiyacım var.","e2":"We need to talk.","e2t":"Konuşmamız gerekiyor (ihtiyacımız var)."},{"w":"neighbor","tr":"komşu","te":"Noun","tt":"İsim","de":"A person living near you","dt":"Yakınınızda yaşayan kişi","e1":"Our neighbors are very quiet.","e1t":"Komşularımız çok sessizdir.","e2":"I helped my neighbor yesterday.","e2t":"Dün komşuma yardım ettim."},{"w":"never","tr":"asla","te":"Adverb","tt":"Zarf","de":"At no time in the past or future","dt":"Geçmişte veya gelecekte hiçbir zaman","e1":"I never eat meat.","e1t":"Asla et yemem.","e2":"He is never late for work.","e2t":"İşe asla geç kalmaz."},{"w":"new","tr":"yeni","te":"Adjective","tt":"Sıfat","de":"Recently made, built, or bought","dt":"Yakın zamanda yapılmış, inşa edilmiş veya alınmış","e1":"I bought a new phone.","e1t":"Yeni bir telefon aldım.","e2":"Welcome to our new house.","e2t":"Yeni evimize hoş geldiniz."},{"w":"next","tr":"sonraki","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Coming immediately after","dt":"Hemen arkasından gelen","e1":"The next bus is at 10 AM.","e1t":"Sonraki otobüs saat 10'da.","e2":"See you next week.","e2t":"Haftaya (sonraki hafta) görüşürüz."},{"w":"night","tr":"gece","te":"Noun","tt":"İsim","de":"The time when it is dark and people sleep","dt":"Havanın karanlık olduğu ve insanların uyuduğu zaman","e1":"I sleep well at night.","e1t":"Gece iyi uyurum.","e2":"The stars shine at night.","e2t":"Yıldızlar gece parlar."},{"w":"nightlight","tr":"gece lambası","te":"Noun","tt":"İsim","de":"A small light kept on at night","dt":"Gece açık bırakılan küçük ışık","e1":"Put a nightlight in the kids' room.","e1t":"Çocuk odasına bir gece lambası koy.","e2":"Dim nightlight.","e2t":"Loş gece lambası."},{"w":"no","tr":"hayır","te":"Exclamation","tt":"Ünlem","de":"Used to give a negative response","dt":"Olumsuz yanıt vermek için kullanılır","e1":"No, I am not tired.","e1t":"Hayır, yorgun değilim.","e2":"No, thank you.","e2t":"Hayır, teşekkürler."},{"w":"noodles","tr":"erişte / makarna","te":"Noun","tt":"İsim (Plural)","de":"Thin strips of pasta or dough","dt":"İnce şeritler halindeki hamur işi","e1":"I like chicken noodles.","e1t":"Tavuklu erişteyi severim.","e2":"A bowl of noodles.","e2t":"Bir kase erişte."},{"w":"noon","tr":"öğle vakti","te":"Noun","tt":"İsim","de":"Twelve o'clock in the day","dt":"Gün ortası, saat 12","e1":"Let's meet at noon.","e1t":"Öğlen buluşalım.","e2":"After noon (afternoon).","e2t":"Öğleden sonra."},{"w":"north","tr":"kuzey","te":"Noun","tt":"İsim","de":"The direction towards the top of a map","dt":"Haritanın üst kısmına doğru olan yön","e1":"Samsun is in the north of Turkey.","e1t":"Samsun Türkiye'nin kuzeyindedir.","e2":"The birds fly north.","e2t":"Kuşlar kuzeye uçar."},{"w":"nose","tr":"burun","te":"Noun","tt":"İsim","de":"The part of the face used for smelling","dt":"Yüzün koklamak için kullanılan kısmı","e1":"My nose is cold.","e1t":"Burnum soğuk.","e2":"He has a long nose.","e2t":"Onun uzun bir burnu var."},{"w":"notebook","tr":"defter","te":"Noun","tt":"İsim","de":"A book with empty pages for writing in","dt":"Yazı yazmak için boş sayfaları olan kitap","e1":"Write your name in the notebook.","e1t":"İsmini deftere yaz.","e2":"I need a new notebook for school.","e2t":"Okul için yeni bir deftere ihtiyacım var."},{"w":"notepad","tr":"not defteri","te":"Noun","tt":"İsim","de":"A book of paper for writing notes","dt":"Not yazmak için kağıtların olduğu defter","e1":"Write your name on the notepad.","e1t":"İsmini not defterine yaz.","e2":"Small notepad.","e2t":"Küçük not defteri."},{"w":"november","tr":"Kasım","te":"Noun","tt":"İsim","de":"The eleventh month of the year","dt":"Yılın on birinci ayı","e1":"It is windy in November.","e1t":"Kasımda hava rüzgarlıdır.","e2":"November is before December.","e2t":"Kasım Aralıktan öncedir."},{"w":"number","tr":"numara","te":"Noun","tt":"İsim","de":"A word or symbol that represents a quantity","dt":"Bir miktarı temsil eden kelime veya sembol","e1":"What is your phone number?","e1t":"Telefon numaran ne?","e2":"Five is my lucky number.","e2t":"Beş benim şanslı numaramdır."},{"w":"nurse","tr":"hemşire","te":"Noun","tt":"İsim","de":"A person who helps doctors and cares for patients","dt":"Doktorlara yardım eden ve hastalarla ilgilenen kişi","e1":"The nurse gave me some medicine.","e1t":"Hemşire bana biraz ilaç verdi.","e2":"She wants to be a nurse.","e2t":"Hemşire olmak istiyor."},{"w":"nut","tr":"fındık / ceviz / kuruyemiş","te":"Noun","tt":"İsim","de":"A fruit with a hard shell and an edible seed","dt":"Sert kabuklu ve yenilebilir çekirdekli meyve","e1":"Don't eat too many nuts.","e1t":"Çok fazla kuruyemiş yeme.","e2":"Walnut is a nut.","e2t":"Ceviz bir kuruyemiştir."},{"w":"oar","tr":"kürek","te":"Noun","tt":"İsim","de":"A pole with a flat blade used for rowing boats","dt":"Tekneleri yürütmek için kullanılan yassı uçlu sopa","e1":"Use the oars to move the boat.","e1t":"Tekneyi hareket ettirmek için kürekleri kullan.","e2":"Wooden oar.","e2t":"Ahşap kürek."},{"w":"ocean","tr":"okyanus","te":"Noun","tt":"İsim","de":"A very large sea","dt":"Çok büyük deniz","e1":"The Atlantic is a big ocean.","e1t":"Atlantik büyük bir okyanustur.","e2":"Sharks live in the ocean.","e2t":"Köpekbalıkları okyanusta yaşar."},{"w":"october","tr":"Ekim","te":"Noun","tt":"İsim","de":"The tenth month of the year","dt":"Yılın onuncu ayı","e1":"The leaves turn yellow in October.","e1t":"Ekimde yapraklar sararır.","e2":"October is a cool month.","e2t":"Ekim serin bir aydır."},{"w":"octopus","tr":"ahtapot","te":"Noun","tt":"İsim","de":"A sea animal with eight arms","dt":"Sekiz kollu deniz canlısı","e1":"The octopus is swimming.","e1t":"Ahtapot yüzüyor.","e2":"Big octopus.","e2t":"Büyük ahtapot."},{"w":"office","tr":"ofis","te":"Noun","tt":"İsim","de":"A room or building where people work at desks","dt":"İnsanların masalarda çalıştığı oda veya bina","e1":"My office is on the fifth floor.","e1t":"Ofisim beşinci katta.","e2":"I stay in the office until 6 PM.","e2t":"Akşam 6'ya kadar ofiste kalırım."},{"w":"often","tr":"sık sık","te":"Adverb","tt":"Zarf","de":"Many times; frequently","dt":"Birçok kez; sıklıkla","e1":"I often visit my grandmother.","e1t":"Büyükannemi sık sık ziyaret ederim.","e2":"Do you often play football?","e2t":"Sık sık futbol oynar mısın?"},{"w":"okay","tr":"tamam","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Used to express agreement","dt":"Anlaşmayı/uygunluğu ifade etmek için kullanılır","e1":"Okay, let's go.","e1t":"Tamam, haydi gidelim.","e2":"Are you okay?","e2t":"İyi misin (Tamam mısın)?"},{"w":"old","tr":"yaşlı / eski","te":"Adjective","tt":"Sıfat","de":"Having lived for a long time or used for a long time","dt":"Uzun süredir yaşayan veya kullanılan","e1":"My grandfather is very old.","e1t":"Büyükbabam çok yaşlı.","e2":"I have an old car.","e2t":"Eski bir arabam var."},{"w":"on","tr":"üzerinde","te":"Preposition","tt":"Edat","de":"Supported by or attached to a surface","dt":"Bir yüzey tarafından desteklenen veya ona bağlı olan","e1":"The book is on the table.","e1t":"Kitap masanın üzerinde.","e2":"My birthday is on Sunday.","e2t":"Doğum günüm Pazar günü."},{"w":"onion","tr":"soğan","te":"Noun","tt":"İsim","de":"A round vegetable with a strong smell and many layers","dt":"Keskin kokulu ve birçok katmanı olan yuvarlak bir sebze","e1":"Cutting onions makes me cry.","e1t":"Soğan doğramak beni ağlatıyor.","e2":"Add some onion to the meal.","e2t":"Yemeğe biraz soğan ekle."},{"w":"only","tr":"sadece","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"And nothing or no one else","dt":"Ve başka hiçbir şey veya hiç kimse değil","e1":"I have only five dollars.","e1t":"Sadece beş dolarım var.","e2":"He is the only child.","e2t":"O tek çocuktur."},{"w":"open","tr":"açmak","te":"Verb","tt":"Fiil","de":"To move something so that an opening is not blocked","dt":"Bir şeyi, bir açıklık engellenmeyecek şekilde hareket ettirmek","e1":"Open the window, please.","e1t":"Lütfen pencereyi aç.","e2":"Can you open the door?","e2t":"Kapıyı açabilir misin?"},{"w":"or","tr":"veya","te":"Conjunction","tt":"Bağlaç","de":"Used to link alternatives","dt":"Alternatifleri birbirine bağlamak için kullanılır","e1":"Do you want tea or coffee?","e1t":"Çay mı istersin kahve mi?","e2":"Is it blue or green?","e2t":"Mavi mi yoksa yeşil mi?"},{"w":"orange","tr":"turuncu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color between red and yellow","dt":"Kırmızı ve sarı arasındaki renk","e1":"The orange juice is fresh.","e1t":"Portakal suyu taze.","e2":"He has an orange ball.","e2t":"Onun turuncu bir topu var."},{"w":"ostrich","tr":"devekuşu","te":"Noun","tt":"İsim","de":"A very large bird that cannot fly but runs fast","dt":"Uçamayan ama hızlı koşan çok büyük kuş","e1":"The ostrich is a very tall bird.","e1t":"Devekuşu çok uzun boylu bir kuştur.","e2":"Fast ostrich.","e2t":"Hızlı devekuşu."},{"w":"other","tr":"diğer","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"The remaining one of two or more","dt":"İki veya daha fazlasından geri kalan","e1":"Where are the other students?","e1t":"Diğer öğrenciler nerede?","e2":"I have other plans.","e2t":"Diğer (başka) planlarım var."},{"w":"outside","tr":"dışında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Not within or beyond the interior","dt":"İçinde olmayan veya iç kısmın ötesinde","e1":"It is raining outside.","e1t":"Dışarıda yağmur yağıyor.","e2":"Wait for me outside the cinema.","e2t":"Beni sinemanın dışında bekle."},{"w":"oven","tr":"fırın","te":"Noun","tt":"İsim","de":"A kitchen machine used for baking food","dt":"Yemek pişirmek için kullanılan mutfak cihazı","e1":"Bake the cake in the oven.","e1t":"Keki fırında pişir.","e2":"Hot oven.","e2t":"Sıcak fırın."},{"w":"over","tr":"üzerinde","te":"Preposition","tt":"Edat","de":"Above or higher than something","dt":"Bir şeyin yukarısında veya daha yüksek bir yerinde","e1":"The bridge is over the river.","e1t":"Köprü nehrin üzerindedir.","e2":"Jump over the fence.","e2t":"Çitin üzerinden atla."},{"w":"pajamas","tr":"pijama","te":"Noun","tt":"İsim (Plural)","de":"Clothes worn for sleeping","dt":"Uyku için giyilen kıyafet","e1":"Wear your pajamas.","e1t":"Pijamalarını giy.","e2":"Blue pajamas.","e2t":"Mavi pijama."},{"w":"panda","tr":"panda","te":"Noun","tt":"İsim","de":"A large black and white animal like a bear","dt":"Ayıya benzeyen siyah","e1":"beyaz büyük hayvan","e1t":"The panda is eating bamboo.","e2":"Panda bambu yiyor.","e2t":"Cute panda."},{"w":"pansy","tr":"hercai menekşe","te":"Noun","tt":"İsim","de":"A colorful garden flower","dt":"Renkli bahçe çiçeği","e1":"There are purple pansies in the garden.","e1t":"Bahçede mor menekşeler var.","e2":"Colorful pansy.","e2t":"Renkli menekşe."},{"w":"pants","tr":"pantolon","te":"Noun","tt":"İsim","de":"Clothing for the lower body with a leg for each","dt":"Alt vücut için, her bacak için ayrı bölümü olan giysi","e1":"These pants are too long.","e1t":"Bu pantolon çok uzun.","e2":"I need to buy new black pants.","e2t":"Yeni siyah bir pantolona ihtiyacım var."},{"w":"paperclip","tr":"ataş","te":"Noun","tt":"İsim","de":"A small wire used for holding papers together","dt":"Kağıtları bir arada tutan küçük tel","e1":"I need a paperclip for these sheets.","e1t":"Bu sayfalar için bir ataşa ihtiyacım var.","e2":"Silver paperclip.","e2t":"Gümüş (metalik) ataş."},{"w":"paragraph","tr":"paragraf","te":"Noun","tt":"İsim","de":"A distinct section of a piece of writing","dt":"Yazının ayrı bir bölümü","e1":"The first paragraph is very interesting.","e1t":"İlk paragraf çok ilginç.","e2":"Write a short paragraph about yourself.","e2t":"Kendin hakkında kısa bir paragraf yaz."},{"w":"parents","tr":"ebeveynler","te":"Noun","tt":"İsim","de":"A person's father and mother","dt":"Bir kişinin annesi ve babası","e1":"My parents live in a small town.","e1t":"Ebeveynlerim küçük bir kasabada yaşıyor.","e2":"Respect your parents.","e2t":"Ebeveynlerine saygı duy."},{"w":"park","tr":"park / park etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A green place for fun; or leave a car","dt":"Yeşil alan; veya araba bırakmak","e1":"Let's walk in the park.","e1t":"Haydi parkta yürüyelim.","e2":"Park the car here.","e2t":"Arabayı buraya park et."},{"w":"party","tr":"parti","te":"Noun","tt":"İsim","de":"A social event with music and food","dt":"Müzikli ve yemekli sosyal etkinlik","e1":"Do you want to come to my party?","e1t":"Partime gelmek ister misin?","e2":"The party was very fun.","e2t":"Parti çok eğlenceliydi."},{"w":"patient","tr":"hasta","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person receiving medical treatment","dt":"Tıbbi tedavi gören kişi","e1":"The doctor is talking to a patient.","e1t":"Doktor bir hastayla konuşuyor.","e2":"Please be patient.","e2t":"Lütfen sabırlı ol."},{"w":"pay","tr":"ödemek","te":"Verb","tt":"Fiil","de":"To give money for goods or services","dt":"Mal veya hizmetler için para vermek","e1":"I pay the bill with my card.","e1t":"Faturayı kartımla öderim.","e2":"How much did you pay for it?","e2t":"Onun için ne kadar ödedin?"},{"w":"pea","tr":"bezelye","te":"Noun","tt":"İsim","de":"A small round green vegetable","dt":"Küçük yuvarlak yeşil sebze","e1":"I don't like green peas.","e1t":"Yeşil bezelyeyi sevmem.","e2":"Sweet pea.","e2t":"Tatlı bezelye."},{"w":"peach","tr":"şeftali","te":"Noun","tt":"İsim","de":"A round fruit with a fuzzy skin and a large stone","dt":"Tüylü kabuklu ve büyük çekirdekli yuvarlak meyve","e1":"This peach is very juicy.","e1t":"Bu şeftali çok sulu.","e2":"Sweet peach.","e2t":"Tatlı şeftali."},{"w":"peacock","tr":"tavus kuşu","te":"Noun","tt":"İsim","de":"A large bird with beautiful colorful tail feathers","dt":"Güzel renkli kuyruk tüyleri olan büyük kuş","e1":"The peacock is showing its tail.","e1t":"Tavus kuşu kuyruğunu gösteriyor.","e2":"Beautiful peacock.","e2t":"Güzel tavus kuşu."},{"w":"pen","tr":"kalem","te":"Noun","tt":"İsim","de":"An instrument for writing or drawing with ink","dt":"Mürekkeple yazmak veya çizmek için bir araç","e1":"Can I borrow your pen?","e1t":"Kalemini ödünç alabilir miyim?","e2":"Use a blue pen for the exam.","e2t":"Sınav için mavi kalem kullan."},{"w":"pencil","tr":"kurşun kalem","te":"Noun","tt":"İsim","de":"A wooden instrument used for writing or drawing","dt":"Yazmak veya çizmek için kullanılan ahşap araç","e1":"I write with a pencil.","e1t":"Kurşun kalemle yazarım.","e2":"Sharpen your pencil, please.","e2t":"Lütfen kalemini aç (sivrit)."},{"w":"penguin","tr":"penguen","te":"Noun","tt":"İsim","de":"A black and white bird that lives in the cold","dt":"Soğuk yerlerde yaşayan siyah","e1":"beyaz kuş","e1t":"Penguins cannot fly.","e2":"Penguenler uçamaz.","e2t":"Little penguin."},{"w":"pepper","tr":"biber","te":"Noun","tt":"İsim","de":"A green, red, or yellow vegetable with seeds","dt":"Çekirdekli yeşil, kırmızı veya sarı bir sebze","e1":"Is this pepper spicy?","e1t":"Bu biber acı mı?","e2":"I am chopping the red peppers.","e2t":"Kırmızı biberleri doğruyorum."},{"w":"pharmacy","tr":"eczane","te":"Noun","tt":"İsim","de":"A shop where you can buy medicine","dt":"İlaç alabileceğiniz dükkan","e1":"I need to go to the pharmacy.","e1t":"Eczaneye gitmem gerekiyor.","e2":"Is there a pharmacy near here?","e2t":"Buralarda yakınlarda bir eczane var mı?"},{"w":"phone","tr":"telefon","te":"Noun","tt":"İsim","de":"A device used to talk to people far away","dt":"Uzaktaki insanlarla konuşmak için kullanılan cihaz","e1":"Answer the phone, please.","e1t":"Lütfen telefona bak (cevap ver).","e2":"I lost my phone.","e2t":"Telefonumu kaybettim."},{"w":"photo","tr":"fotoğraf","te":"Noun","tt":"İsim","de":"A picture taken with a camera","dt":"Kamera ile çekilen resim","e1":"I want to take a photo of you.","e1t":"Senin bir fotoğrafını çekmek istiyorum.","e2":"Look at these old photos.","e2t":"Bu eski fotoğraflara bak."},{"w":"pickle","tr":"turşu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vegetable kept in vinegar and salt","dt":"Sirke ve tuzda bekletilmiş sebze","e1":"Put a pickle in my sandwich.","e1t":"Sandviçime bir turşu koy.","e2":"Cucumber pickle.","e2t":"Salatalık turşusu."},{"w":"picture","tr":"resim","te":"Noun","tt":"İsim","de":"A drawing, painting, or photograph","dt":"Çizim, boyama veya fotoğraf","e1":"There is a picture of a cat on the wall.","e1t":"Duvarda bir kedi resmi var.","e2":"Draw a picture of your house.","e2t":"Evinin bir resmini çiz."},{"w":"pill","tr":"hap","te":"Noun","tt":"İsim","de":"A small round piece of medicine","dt":"Küçük yuvarlak ilaç parçası","e1":"Swallow the pill with some water.","e1t":"Hapı biraz suyla yut.","e2":"I take two pills a day.","e2t":"Günde iki hap alıyorum."},{"w":"pink","tr":"pembe","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"A pale red color","dt":"Soluk kırmızı renk","e1":"Pink is her favorite color.","e1t":"Pembe onun en sevdiği renktir.","e2":"These flowers are pink.","e2t":"Bu çiçekler pembe."},{"w":"pirate","tr":"korsan","te":"Noun","tt":"İsim","de":"A person who attacks ships at sea","dt":"Denizde gemilere saldıran kişi","e1":"The pirate has a treasure map.","e1t":"Korsanın bir hazine haritası var.","e2":"Scary pirate.","e2t":"Korkunç korsan."},{"w":"plan","tr":"plan","te":"Noun/Verb","tt":"İsim/Fiil","de":"A detailed proposal for doing something","dt":"Bir şeyi yapmak için ayrıntılı teklif/tasarı","e1":"What is your plan for the weekend?","e1t":"Hafta sonu için planın ne?","e2":"I am planning a surprise party.","e2t":"Sürpriz bir parti planlıyorum."},{"w":"plate","tr":"tabak","te":"Noun","tt":"İsim","de":"A flat dish used for eating or serving food","dt":"Yemek yemek veya servis etmek için kullanılan düz kap","e1":"Put the cake on a small plate.","e1t":"Keki küçük bir tabağa koy.","e2":"The plate is empty.","e2t":"Tabak boş."},{"w":"play","tr":"oynamak","te":"Verb","tt":"Fiil","de":"To engage in activity for enjoyment","dt":"Keyif için bir aktiviteyle uğraşmak","e1":"Children like to play in the park.","e1t":"Çocuklar parkta oynamayı sever.","e2":"Do you want to play a game?","e2t":"Bir oyun oynamak ister misin?"},{"w":"playground","tr":"oyun alanı / park","te":"Noun","tt":"İsim","de":"An area outside for children to play","dt":"Çocukların oynaması için dışarıdaki alan","e1":"The kids are at the playground.","e1t":"Çocuklar oyun parkındalar.","e2":"School playground.","e2t":"Okul bahçesi (oyun alanı)."},{"w":"please","tr":"lütfen","te":"Adverb","tt":"Zarf","de":"Used to ask for something politely","dt":"Bir şeyi nazikçe istemek için kullanılır","e1":"A cup of tea, please.","e1t":"Bir fincan çay, lütfen.","e2":"Please open the door.","e2t":"Lütfen kapıyı aç."},{"w":"police","tr":"polis","te":"Noun","tt":"İsim","de":"An official organization that keeps public order","dt":"Kamu düzenini sağlayan resmi kuruluş/görevli","e1":"Call the police!","e1t":"Polisi ara!","e2":"The police officer stopped the car.","e2t":"Polis memuru arabayı durdurdu."},{"w":"pond","tr":"gölet","te":"Noun","tt":"İsim","de":"A small area of still water","dt":"Küçük durgun su birikintisi","e1":"Ducks are swimming in the pond.","e1t":"Ördekler gölette yüzüyor.","e2":"A small pond.","e2t":"Küçük bir gölet."},{"w":"pony","tr":"midilli","te":"Noun","tt":"İsim","de":"A type of small horse","dt":"Küçük bir at türü","e1":"The girl is riding a pony.","e1t":"Kız midilliye biniyor.","e2":"Brown pony.","e2t":"Kahverengi midilli."},{"w":"popcorn","tr":"patlamış mısır","te":"Noun","tt":"İsim","de":"Corn that is heated until it bursts into white pieces","dt":"Beyaz parçalara dönüşene kadar ısıtılan mısır","e1":"Eat popcorn while watching a movie.","e1t":"Film izlerken patlamış mısır ye.","e2":"Salty popcorn.","e2t":"Tuzlu patlamış mısır."},{"w":"postman","tr":"postacı","te":"Noun","tt":"İsim","de":"A person who delivers letters to your house","dt":"Eve mektup getiren kişi","e1":"The postman is here with a letter.","e1t":"Postacı bir mektupla burada.","e2":"Kind postman.","e2t":"Nazik postacı."},{"w":"potato","tr":"patates","te":"Noun","tt":"İsim","de":"A round white starchy vegetable that grows underground","dt":"Yer altında yetişen yuvarlak, beyaz nişastalı bir sebze","e1":"I like fried potatoes.","e1t":"Kızarmış patatesi severim.","e2":"Peel the potatoes for dinner.","e2t":"Akşam yemeği için patatesleri soy."},{"w":"present","tr":"hediye / şu an","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A gift or the period of time now","dt":"Hediye veya şu anki zaman dilimi","e1":"She gave me a birthday present.","e1t":"Bana bir doğum günü hediyesi verdi.","e2":"At present, I am very busy.","e2t":"Şu anda çok meşgulüm."},{"w":"price","tr":"fiyat","te":"Noun","tt":"İsim","de":"The amount of money you pay for something","dt":"Bir şey için ödediğiniz para miktarı","e1":"What is the price of this bag?","e1t":"Bu çantanın fiyatı ne?","e2":"The prices are very high here.","e2t":"Burada fiyatlar çok yüksek."},{"w":"problem","tr":"sorun","te":"Noun","tt":"İsim","de":"A situation that needs to be solved","dt":"Çözülmesi gereken durum","e1":"I have a problem with my car.","e1t":"Arabamla ilgili bir sorunum var.","e2":"No problem!","e2t":"Sorun değil!"},{"w":"project","tr":"proje","te":"Noun","tt":"İsim","de":"A piece of planned work that takes time","dt":"Zaman alan, planlanmış bir iş parçası","e1":"We are working on a new project.","e1t":"Yeni bir proje üzerinde çalışıyoruz.","e2":"When is the project deadline?","e2t":"Projenin son teslim tarihi ne zaman?"},{"w":"puddle","tr":"su birikintisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small pool of water on the ground after rain","dt":"Yağmurdan sonra yerdeki küçük su kütlesi","e1":"Don't jump in the puddle.","e1t":"Su birikintisine atlama.","e2":"Muddy puddle.","e2t":"Çamurlu birikinti."},{"w":"pumpkin","tr":"kabak / bal kabağı","te":"Noun","tt":"İsim","de":"A large round orange vegetable","dt":"Büyük yuvarlak turuncu sebze","e1":"We make soup from pumpkin.","e1t":"Kabaktan çorba yaparız.","e2":"Big pumpkin.","e2t":"Büyük kabak."},{"w":"purple","tr":"mor","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"A color between red and blue","dt":"Kırmızı ve mavi arasındaki bir renk","e1":"She has a purple bag.","e1t":"Onun mor bir çantası var.","e2":"My favorite color is purple.","e2t":"En sevdiğim renk mor."},{"w":"question","tr":"soru","te":"Noun","tt":"İsim","de":"A sentence that asks for information","dt":"Bilgi isteyen cümle","e1":"Can I ask a question?","e1t":"Bir soru sorabilir miyim?","e2":"Answer the questions on page 10.","e2t":"10. sayfadaki soruları cevapla."},{"w":"quiet","tr":"sessiz","te":"Adjective","tt":"Sıfat","de":"Making very little noise","dt":"Çok az gürültü çıkaran","e1":"Please be quiet in the library.","e1t":"Lütfen kütüphanede sessiz olun.","e2":"It is a quiet street.","e2t":"Burası sessiz bir sokak."},{"w":"rabbit","tr":"tavşan","te":"Noun","tt":"İsim","de":"A small animal with long ears","dt":"Uzun kulaklı küçük hayvan","e1":"The rabbit is eating a carrot.","e1t":"Tavşan havuç yiyor.","e2":"White rabbit.","e2t":"Beyaz tavşan."},{"w":"radio","tr":"radyo","te":"Noun","tt":"İsim","de":"A device that receives audio signals","dt":"Ses sinyallerini alan cihaz","e1":"I listen to the radio in the car.","e1t":"Arabada radyo dinlerim.","e2":"Turn up the radio, I like this song.","e2t":"Radyonun sesini aç, bu şarkıyı seviyorum."},{"w":"rain","tr":"yağmur","te":"Noun","tt":"İsim","de":"Water that falls from the clouds in drops","dt":"Bulutlardan damlalar halinde düşen su","e1":"I like the smell of rain.","e1t":"Yağmurun kokusunu severim.","e2":"It started to rain.","e2t":"Yağmur yağmaya başladı."},{"w":"raincoat","tr":"yağmurluk","te":"Noun","tt":"İsim","de":"A coat that you wear when it rains","dt":"Yağmur yağdığında giyilen ceket","e1":"Wear your raincoat.","e1t":"Yağmurluğunu giy.","e2":"Yellow raincoat.","e2t":"Sarı yağmurluk."},{"w":"rainy","tr":"yağmurlu","te":"Adjective","tt":"Sıfat","de":"Having a lot of rain","dt":"Çok yağmuru olan","e1":"I don't like rainy weather.","e1t":"Yağmurlu havayı sevmem.","e2":"It will be rainy tomorrow.","e2t":"Yarın hava yağmurlu olacak."},{"w":"read","tr":"okumak","te":"Verb","tt":"Fiil","de":"To look at and understand written words","dt":"Yazılı kelimelere bakmak ve anlamak","e1":"I like to read books.","e1t":"Kitap okumayı severim.","e2":"Read the sentence aloud.","e2t":"Cümleyi yüksek sesle oku."},{"w":"really","tr":"gerçekten","te":"Adverb","tt":"Zarf","de":"In actual fact or to emphasize something","dt":"Gerçekte veya bir şeyi vurgulamak için","e1":"I really like this song.","e1t":"Bu şarkıyı gerçekten seviyorum.","e2":"Is he really a doctor?","e2t":"O gerçekten bir doktor mu?"},{"w":"reason","tr":"sebep","te":"Noun","tt":"İsim","de":"A cause or explanation for something","dt":"Bir şey için neden veya açıklama","e1":"What is the reason for your delay?","e1t":"Gecikmenizin sebebi nedir?","e2":"Give me one good reason.","e2t":"Bana iyi bir sebep söyle."},{"w":"receipt","tr":"fiş","te":"Noun","tt":"İsim","de":"A piece of paper that proves you paid for something","dt":"Bir şey için ödeme yaptığınızı kanıtlayan kağıt parçası","e1":"Keep the receipt for the guarantee.","e1t":"Garanti için fişi sakla.","e2":"Can I get a receipt, please?","e2t":"Bir fiş alabilir miyim lütfen?"},{"w":"red","tr":"kırmızı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of blood or tomatoes","dt":"Kanın veya domatesin rengi","e1":"She has a red dress.","e1t":"Onun kırmızı bir elbisesi var.","e2":"The stop sign is red.","e2t":"Dur tabelası kırmızıdır."},{"w":"remember","tr":"hatırlamak","te":"Verb","tt":"Fiil","de":"To bring back to one's mind an awareness of","dt":"Bir farkındalığı zihne geri getirmek","e1":"I remember you.","e1t":"Seni hatırlıyorum.","e2":"Please remember to close the door.","e2t":"Lütfen kapıyı kapatmayı hatırla."},{"w":"restaurant","tr":"restoran","te":"Noun","tt":"İsim","de":"A place where people pay to sit and eat meals","dt":"İnsanların oturup yemek yemek için ödeme yaptığı yer","e1":"This is a very expensive restaurant.","e1t":"Bu çok pahalı bir restoran.","e2":"We went to a Chinese restaurant.","e2t":"Bir Çin restoranına gittik."},{"w":"rice","tr":"pirinç","te":"Noun","tt":"İsim","de":"Small white or brown grains used as food","dt":"Yiyecek olarak kullanılan küçük beyaz veya kahverengi taneler","e1":"We eat rice with chicken.","e1t":"Tavukla birlikte pirinç yeriz.","e2":"Rice is popular in Asia.","e2t":"Pirinç Asya'da popülerdir."},{"w":"right","tr":"sağ / doğru","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The opposite of left or being correct","dt":"Solun zıttı veya doğru olma durumu","e1":"Turn right after the bank.","e1t":"Bankadan sonra sağa dön.","e2":"You are right.","e2t":"Haklısın (Doğrusun)."},{"w":"ring","tr":"yüzük","te":"Noun","tt":"İsim","de":"A small circular band worn on a finger","dt":"Parmağa takılan küçük dairesel bant","e1":"This is a gold ring.","e1t":"Bu altın bir yüzük.","e2":"She wears a ring on her finger.","e2t":"Parmağında bir yüzük taşıyor."},{"w":"river","tr":"nehir","te":"Noun","tt":"İsim","de":"A large natural stream of water","dt":"Büyük doğal su akıntısı","e1":"We are walking by the river.","e1t":"Nehir kenarında yürüyoruz.","e2":"The river is very long.","e2t":"Nehir çok uzun."},{"w":"road","tr":"yol","te":"Noun","tt":"İsim","de":"A long hard surface for vehicles to travel on","dt":"Araçların seyahat etmesi için uzun sert yüzey","e1":"The road to the village is narrow.","e1t":"Köye giden yol dar.","e2":"Be careful when you cross the road.","e2t":"Yolun karşısına geçerken dikkatli ol."},{"w":"rollerblades","tr":"paten","te":"Noun","tt":"İsim (Plural)","de":"Boots with wheels in a line for skating","dt":"Kaymak için tek sıra tekerlekli botlar","e1":"I can skate with rollerblades.","e1t":"Patenlerle kayabilirim.","e2":"New rollerblades.","e2t":"Yeni patenler."},{"w":"rollercoaster","tr":"hız treni","te":"Noun","tt":"İsim","de":"A track at a fairground that goes up and down very fast","dt":"Lunaparklarda çok hızlı inip çıkan raylı eğlence aracı","e1":"I am afraid of the rollercoaster.","e1t":"Hız treninden korkarım.","e2":"Fast rollercoaster.","e2t":"Hızlı tren."},{"w":"roof","tr":"çatı","te":"Noun","tt":"İsim","de":"The structure that covers the top of a building","dt":"Bir binanın üstünü örten yapı","e1":"There is a cat on the roof.","e1t":"Çatıda bir kedi var.","e2":"The roof of the house is red.","e2t":"Evin çatısı kırmızı."},{"w":"room","tr":"oda","te":"Noun","tt":"İsim","de":"A part of a house enclosed by walls","dt":"Bir evin duvarlarla çevrili bir bölümü","e1":"There are four rooms in the house.","e1t":"Evde dört oda var.","e2":"This room is very bright.","e2t":"Bu oda çok aydınlık."},{"w":"rugby","tr":"ragbi","te":"Noun","tt":"İsim","de":"A sport played by two teams with an oval ball","dt":"Oval bir topla iki takım arasında oynanan spor","e1":"He plays rugby every weekend.","e1t":"Her hafta sonu ragbi oynar.","e2":"Rugby ball.","e2t":"Ragbi topu."},{"w":"ruler","tr":"cetvel","te":"Noun","tt":"İsim","de":"A straight strip of wood or plastic used to measure","dt":"Ölçmek için kullanılan düz ahşap veya plastik parça","e1":"Use a ruler to draw a straight line.","e1t":"Düz bir çizgi çizmek için cetvel kullan.","e2":"My ruler is 30 centimeters long.","e2t":"Cetvelim 30 santimetre uzunluğunda."},{"w":"run","tr":"koşmak","te":"Verb","tt":"Fiil","de":"To move fast on foot","dt":"Yaya olarak hızlı hareket etmek","e1":"Don't run in the corridor.","e1t":"Koridorda koşma.","e2":"He can run very fast.","e2t":"O çok hızlı koşabilir."},{"w":"running","tr":"koşu","te":"Noun","tt":"İsim","de":"The activity of moving fast on foot","dt":"Yaya olarak hızlı hareket etme aktivitesi","e1":"I go running every morning.","e1t":"Her sabah koşuya çıkarım.","e2":"Running in the rain is fun.","e2t":"Yağmurda koşmak eğlencelidir."},{"w":"sad","tr":"üzgün","te":"Adjective","tt":"Sıfat","de":"Feeling or showing sorrow","dt":"Üzüntü hisseden veya gösteren","e1":"Why are you so sad?","e1t":"Neden bu kadar üzgünsün?","e2":"It was a sad story.","e2t":"Üzücü bir hikayeydi."},{"w":"safe","tr":"güvenli / kasa","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not in danger","dt":"Tehlikede olmayan","e1":"Is it safe here?","e1t":"Burası güvenli mi?","e2":"Put the money in the safe.","e2t":"Parayı kasaya koy."},{"w":"sailing","tr":"yelkencilik","te":"Noun","tt":"İsim","de":"The sport or activity of using boats with sails","dt":"Yelkenli teknelerle yapılan spor veya aktivite","e1":"I like sailing in summer.","e1t":"Yazın yelkencilik yapmayı severim.","e2":"Go sailing.","e2t":"Yelken açmak."},{"w":"salad","tr":"salata","te":"Noun","tt":"İsim","de":"A cold dish of mixed vegetables","dt":"Karışık sebzelerden yapılan soğuk yemek","e1":"I want a green salad.","e1t":"Yeşil bir salata istiyorum.","e2":"Fruit salad.","e2t":"Meyve salatası."},{"w":"salary","tr":"maaş","te":"Noun","tt":"İsim","de":"The money that you receive for your work","dt":"İşiniz için aldığınız para","e1":"He gets a high salary.","e1t":"Yüksek bir maaş alıyor.","e2":"My salary is paid every month.","e2t":"Maaşım her ay ödenir."},{"w":"salt","tr":"tuz","te":"Noun","tt":"İsim","de":"A white mineral used to flavor and preserve food","dt":"Yemeklere tat vermek ve korumak için kullanılan beyaz mineral","e1":"This soup needs more salt.","e1t":"Bu çorbanın daha fazla tuza ihtiyacı var.","e2":"Pass me the salt, please.","e2t":"Lütfen tuzu bana uzat."},{"w":"saturday","tr":"Cumartesi","te":"Noun","tt":"İsim","de":"The first day of the weekend","dt":"Hafta sonunun ilk günü","e1":"I wake up late on Saturday.","e1t":"Cumartesi geç uyanırım.","e2":"Saturday is a holiday.","e2t":"Cumartesi tatildir."},{"w":"sausage","tr":"sosis","te":"Noun","tt":"İsim","de":"Meat in a thin tube shape","dt":"Boru şeklindeki et yiyeceği","e1":"We have sausages for breakfast.","e1t":"Kahvaltıda sosis yeriz.","e2":"Beef sausage.","e2t":"Sığır eti sosisi."},{"w":"saw","tr":"testere / testereyle kesmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool with sharp teeth for cutting wood","dt":"Odun kesmek için keskin dişli araç","e1":"Use a saw to cut the board.","e1t":"Tahtayı kesmek için testere kullan.","e2":"Hand saw.","e2t":"El testeresi."},{"w":"say","tr":"söylemek / demek","te":"Verb","tt":"Fiil","de":"Speak words","dt":"Kelimeleri telaffuz etmek","e1":"What did you say?","e1t":"Ne dedin?","e2":"Say it again.","e2t":"Tekrar söyle."},{"w":"scarecrow","tr":"korkuluk","te":"Noun","tt":"İsim","de":"A model of a person used to frighten birds away from crops","dt":"Kuşları ekinlerden uzaklaştırmak için kullanılan insan modeli","e1":"There is a scarecrow in the field.","e1t":"Tarlada bir korkuluk var.","e2":"Funny scarecrow.","e2t":"Komik korkuluk."},{"w":"scarf","tr":"atkı","te":"Noun","tt":"İsim","de":"A piece of fabric worn around the neck","dt":"Boyun etrafına takılan kumaş parçası","e1":"Wear a scarf, it's cold outside.","e1t":"Atkı tak, dışarısı soğuk.","e2":"I like your colorful scarf.","e2t":"Renkli atkını sevdim."},{"w":"school","tr":"okul","te":"Noun","tt":"İsim","de":"A place where children go to be educated","dt":"Çocukların eğitim almak için gittiği yer","e1":"I go to school by bus.","e1t":"Okula otobüsle giderim.","e2":"The school is closed today.","e2t":"Okul bugün kapalı."},{"w":"scooter","tr":"skuter","te":"Noun","tt":"İsim","de":"A small vehicle with two wheels","dt":"İki tekerlekli küçük taşıt","e1":"He rides a scooter to school.","e1t":"Okula skuter ile gider.","e2":"Electric scooter.","e2t":"Elektrikli skuter."},{"w":"sea","tr":"deniz","te":"Noun","tt":"İsim","de":"A large area of salt water","dt":"Büyük tuzlu su alanı","e1":"The sea is very calm today.","e1t":"Bugün deniz çok sakin.","e2":"I love swimming in the sea.","e2t":"Denizde yüzmeyi seviyorum."},{"w":"seahorse","tr":"denizatı","te":"Noun","tt":"İsim","de":"A small fish that looks like a horse","dt":"Atı andıran küçük balık","e1":"Look at the tiny seahorse.","e1t":"Şu minicik denizatına bak.","e2":"Little seahorse.","e2t":"Küçük denizatı."},{"w":"second","tr":"ikinci","te":"Ordinal Number","tt":"Sıra Numarası","de":"Number two in a sequence","dt":"Sıralamada iki numara","e1":"January is the first month, February is the second.","e1t":"Ocak birinci aydır, Şubat ikincidir.","e2":"He finished in second place.","e2t":"İkinci sırada bitirdi."},{"w":"see","tr":"görmek","te":"Verb","tt":"Fiil","de":"To become aware of something using your eyes","dt":"Gözlerini kullanarak bir şeyin farkına varmak","e1":"I can see the birds.","e1t":"Kuşları görebiliyorum.","e2":"Did you see that movie?","e2t":"O filmi gördün mü?"},{"w":"seesaw","tr":"tahterevalli","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long board that children sit on and move up and down","dt":"Çocukların üzerine oturup aşağı yukarı hareket ettiği uzun tahta","e1":"Children are playing on the seesaw.","e1t":"Çocuklar tahterevallide oynuyor.","e2":"Play on the seesaw.","e2t":"Tahterevallide oynamak."},{"w":"sell","tr":"satmak","te":"Verb","tt":"Fiil","de":"To give something in exchange for money","dt":"Para karşılığında bir şey vermek","e1":"They sell fresh bread here.","e1t":"Burada taze ekmek satıyorlar.","e2":"I want to sell my old bike.","e2t":"Eski bisikletimi satmak istiyorum."},{"w":"sentence","tr":"cümle","te":"Noun","tt":"İsim","de":"A set of words that is complete in itself","dt":"Kendi içinde tam olan kelimeler seti","e1":"Write a sentence with 'apple'.","e1t":"'Apple' ile bir cümle kur (yaz).","e2":"This is a very long sentence.","e2t":"Bu çok uzun bir cümle."},{"w":"september","tr":"Eylül","te":"Noun","tt":"İsim","de":"The ninth month of the year","dt":"Yılın dokuzuncu ayı","e1":"Schools open in September.","e1t":"Okullar Eylülde açılır.","e2":"Autumn starts in September.","e2t":"Sonbahar Eylülde başlar."},{"w":"service","tr":"hizmet","te":"Noun","tt":"İsim","de":"The action of helping or doing work for someone","dt":"Birine yardım etme veya iş yapma eylemi","e1":"The service in this restaurant is excellent.","e1t":"Bu restorandaki hizmet mükemmel.","e2":"Customer service is on the second floor.","e2t":"Müşteri hizmetleri ikinci katta."},{"w":"shark","tr":"köpek balığı","te":"Noun","tt":"İsim","de":"A large sea fish with sharp teeth","dt":"Keskin dişli, büyük deniz balığı","e1":"The shark is swimming fast.","e1t":"Köpek balığı hızlı yüzüyor.","e2":"White shark.","e2t":"Beyaz köpek balığı."},{"w":"sheep","tr":"koyun","te":"Noun","tt":"İsim","de":"A farm animal kept for its wool or meat","dt":"Yünü veya eti için beslenen çiftlik hayvanı","e1":"The sheep are eating grass.","e1t":"Koyunlar ot yiyor.","e2":"I saw a flock of sheep.","e2t":"Bir koyun sürüsü gördüm."},{"w":"shirt","tr":"gömlek","te":"Noun","tt":"İsim","de":"A piece of clothing for the upper body","dt":"Üst vücut için bir kıyafet parçası","e1":"He wears a white shirt for work.","e1t":"İş için beyaz bir gömlek giyer.","e2":"Your shirt is very nice.","e2t":"Gömleğin çok hoş."},{"w":"shoes","tr":"ayakkabı","te":"Noun","tt":"İsim","de":"Coverings for the feet","dt":"Ayaklar için örtü/koruyucu","e1":"Take off your shoes, please.","e1t":"Lütfen ayakkabılarını çıkar.","e2":"My shoes are dirty.","e2t":"Ayakkabılarım kirli."},{"w":"shop","tr":"mağaza","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where you buy things","dt":"Bir şeyler satın aldığınız yer","e1":"The shop is open until midnight.","e1t":"Mağaza gece yarısına kadar açık.","e2":"I like to shop for clothes.","e2t":"Kıyafet alışverişi yapmayı severim."},{"w":"short","tr":"kısa","te":"Adjective","tt":"Sıfat","de":"Not long in distance or time","dt":"Mesafe veya zaman olarak uzun olmayan","e1":"It was a very short movie.","e1t":"Çok kısa bir filmdi.","e2":"He is wearing short pants.","e2t":"Kısa pantolon giyiyor."},{"w":"shorts","tr":"şort","te":"Noun","tt":"İsim (Plural)","de":"Short trousers","dt":"Kısa pantolon","e1":"I wear shorts in summer.","e1t":"Yazın şort giyerim.","e2":"Blue shorts.","e2t":"Mavi şort."},{"w":"show","tr":"göstermek","te":"Verb","tt":"Fiil","de":"To allow something to be seen","dt":"Bir şeyin görülmesine izin vermek","e1":"Show me your new shoes.","e1t":"Bana yeni ayakkabılarını göster.","e2":"He showed me the way.","e2t":"Bana yolu gösterdi."},{"w":"sing","tr":"şarkı söylemek","te":"Verb","tt":"Fiil","de":"To make musical sounds with the voice","dt":"Sesle müzikal sesler çıkarmak","e1":"She can sing very well.","e1t":"O çok iyi şarkı söyleyebilir.","e2":"Sing a song.","e2t":"Bir şarkı söylemek."},{"w":"sister","tr":"kız kardeş","te":"Noun","tt":"İsim","de":"A girl or woman who has the same parents","dt":"Aynı ebeveynlere sahip kız veya kadın","e1":"My little sister is five years old.","e1t":"Küçük kız kardeşim beş yaşında.","e2":"I have two sisters.","e2t":"İki kız kardeşim var."},{"w":"sit","tr":"oturmak","te":"Verb","tt":"Fiil","de":"To rest one's weight on one's bottom","dt":"Ağırlığını kalçasına vererek dinlenmek","e1":"Please sit down.","e1t":"Lütfen oturun.","e2":"I sit on the sofa.","e2t":"Kanepede otururum."},{"w":"skate","tr":"paten kaymak / paten","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move on ice or a hard surface using boots with wheels or blades","dt":"Tekerlekli veya bıçaklı botlarla kaymak","e1":"Can you skate on ice?","e1t":"Buzda paten kayabilir misin?","e2":"Ice skates.","e2t":"Buz pateni."},{"w":"skin","tr":"cilt","te":"Noun","tt":"İsim","de":"The natural outer layer of the body","dt":"Vücudun doğal dış katmanı","e1":"Protect your skin from the sun.","e1t":"Cildini güneşten koru.","e2":"She has very soft skin.","e2t":"Onun çok yumuşak bir cildi var."},{"w":"skipping","tr":"ip atlama","te":"Noun","tt":"İsim","de":"The activity of jumping over a rope","dt":"Bir ipin üzerinden atlama aktivitesi","e1":"She is very good at skipping.","e1t":"İp atlamada çok iyidir.","e2":"Skipping rope.","e2t":"Atlama ipi."},{"w":"skirt","tr":"etek","te":"Noun","tt":"İsim","de":"A woman's garment that hangs from the waist","dt":"Belden sarkan kadın giysisi","e1":"She is wearing a long skirt.","e1t":"Uzun bir etek giyiyor.","e2":"The school skirt is blue.","e2t":"Okul eteği mavi."},{"w":"sky","tr":"gökyüzü","te":"Noun","tt":"İsim","de":"The space above the earth","dt":"Dünyanın üzerindeki boşluk","e1":"The sky is blue and clear.","e1t":"Gökyüzü mavi ve açık.","e2":"Birds are flying in the sky.","e2t":"Kuşlar gökyüzünde uçuyorlar."},{"w":"sledge","tr":"kızak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle used for sliding over snow","dt":"Kar üzerinde kaymak için kullanılan araç","e1":"Let's go down the hill on a sledge.","e1t":"Tepeden kızakla aşağı inelim.","e2":"Wooden sledge.","e2t":"Ahşap kızak."},{"w":"sleep","tr":"uyumak","te":"Verb","tt":"Fiil","de":"To rest with eyes closed and mind unconscious","dt":"Gözler kapalı ve zihin bilinci kapalı halde dinlenmek","e1":"I need to sleep eight hours.","e1t":"Sekiz saat uyumam gerekiyor.","e2":"The baby is sleeping now.","e2t":"Bebek şu an uyuyor."},{"w":"slippers","tr":"terlik","te":"Noun","tt":"İsim (Plural)","de":"Soft shoes that you wear inside a house","dt":"Ev içinde giyilen yumuşak ayakkabılar","e1":"Put on your slippers.","e1t":"Terliklerini giy.","e2":"Warm slippers.","e2t":"Sıcak terlikler."},{"w":"slow","tr":"yavaş","te":"Adjective","tt":"Sıfat","de":"Moving or operating at a low speed","dt":"Düşük hızda hareket eden veya çalışan","e1":"The bus is very slow today.","e1t":"Otobüs bugün çok yavaş.","e2":"Turtles are slow animals.","e2t":"Kaplumbağalar yavaş hayvanlardır."},{"w":"small","tr":"küçük","te":"Adjective","tt":"Sıfat","de":"Little in size or amount","dt":"Boyut veya miktar olarak az/küçük","e1":"I have a small car.","e1t":"Küçük bir arabam var.","e2":"The bird is very small.","e2t":"Kuş çok küçük."},{"w":"smell","tr":"koklamak","te":"Verb","tt":"Fiil","de":"To perceive the scent of something with the nose","dt":"Bir şeyin kokusunu burunla algılamak","e1":"These flowers smell good.","e1t":"Bu çiçekler güzel kokuyor.","e2":"Smell this perfume.","e2t":"Bu parfümü kokla."},{"w":"snow","tr":"kar","te":"Noun","tt":"İsim","de":"Soft white frozen water falling from the sky","dt":"Gökyüzünden düşen yumuşak beyaz donmuş su","e1":"Children are playing in the snow.","e1t":"Çocuklar karda oynuyorlar.","e2":"Everything is white with snow.","e2t":"Her yer karla bembeyaz."},{"w":"snowy","tr":"karlı","te":"Adjective","tt":"Sıfat","de":"Covered with snow or characterized by snow","dt":"Kar ile kaplı veya karla karakterize edilen","e1":"We went skiing on a snowy day.","e1t":"Karlı bir günde kayağa gittik.","e2":"The mountains look snowy.","e2t":"Dağlar karlı görünüyor."},{"w":"so","tr":"bu yüzden","te":"Conjunction/Adverb","tt":"Bağlaç/Zarf","de":"For that reason; therefore","dt":"Bu nedenle; dolayısıyla","e1":"It was raining, so I stayed home.","e1t":"Yağmur yağıyordu, bu yüzden evde kaldım.","e2":"I am hungry, so I will eat.","e2t":"Açım, bu yüzden yemek yiyeceğim."},{"w":"socks","tr":"çorap","te":"Noun","tt":"İsim","de":"Clothing worn on the feet inside shoes","dt":"Ayakkabı içine giyilen ayak giysisi","e1":"I can't find my socks.","e1t":"Çoraplarımı bulamıyorum.","e2":"These are warm winter socks.","e2t":"Bunlar sıcak tutan kışlık çoraplar."},{"w":"sofa","tr":"kanepe","te":"Noun","tt":"İsim","de":"A long comfortable seat for two or more people","dt":"İki veya daha fazla kişi için uzun ve rahat koltuk","e1":"We sat on the sofa and watched TV.","e1t":"Kanepede oturduk ve TV izledik.","e2":"My cat is sleeping on the sofa.","e2t":"Kedim kanepenin üzerinde uyuyor."},{"w":"solution","tr":"çözüm","te":"Noun","tt":"İsim","de":"A means of solving a problem","dt":"Bir sorunu çözme yolu","e1":"We need a quick solution.","e1t":"Hızlı bir çözüme ihtiyacımız var.","e2":"This is the best solution for us.","e2t":"Bu bizim için en iyi çözüm."},{"w":"some","tr":"bazı","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"An unspecified amount or number","dt":"Belirlenmemiş miktar veya sayı","e1":"I need some water.","e1t":"Biraz suya ihtiyacım var.","e2":"Some people like spicy food.","e2t":"Bazı insanlar baharatlı yiyecekleri sever."},{"w":"sometimes","tr":"bazen","te":"Adverb","tt":"Zarf","de":"Occasionally; at times","dt":"Ara sıra; zaman zaman","e1":"Sometimes I walk to school.","e1t":"Bazen okula yürürüm.","e2":"It is sometimes rainy in spring.","e2t":"İlkbaharda bazen yağmurlu olur."},{"w":"son","tr":"oğul","te":"Noun","tt":"İsim","de":"A person's male child","dt":"Bir kişinin erkek çocuğu","e1":"They have one son and two daughters.","e1t":"Bir oğulları ve iki kızları var.","e2":"He is a good son.","e2t":"O iyi bir oğul."},{"w":"song","tr":"şarkı","te":"Noun","tt":"İsim","de":"A short piece of music with words","dt":"Sözleri olan kısa müzik parçası","e1":"This is my favorite song.","e1t":"Bu benim en sevdiğim şarkı.","e2":"Sing a song for us.","e2t":"Bizim için bir şarkı söyle."},{"w":"sorry","tr":"üzgünüm","te":"Adjective/Exclamation","tt":"Sıfat/Ünlem","de":"Feeling regret or pity","dt":"Pişmanlık veya acıma hissetme","e1":"I am sorry I am late.","e1t":"Geç kaldığım için üzgünüm.","e2":"Sorry, can you repeat that?","e2t":"Üzgünüm, onu tekrar edebilir misin?"},{"w":"south","tr":"güney","te":"Noun","tt":"İsim","de":"The direction towards the bottom of a map","dt":"Haritanın alt kısmına doğru olan yön","e1":"Antalya is in the south.","e1t":"Antalya güneydedir.","e2":"The wind is blowing from the south.","e2t":"Rüzgar güneyden esiyor."},{"w":"spaceship","tr":"uzay gemisi","te":"Noun","tt":"İsim","de":"A vehicle that travels in space","dt":"Uzayda yolculuk yapan araç","e1":"The spaceship is near Mars.","e1t":"Uzay gemisi Mars'ın yakınında.","e2":"Fast spaceship.","e2t":"Hızlı uzay gemisi."},{"w":"spaghetti","tr":"spagetti / makarna","te":"Noun","tt":"İsim","de":"Pasta made in long, thin strings","dt":"Uzun, ince şeritler halindeki makarna","e1":"I love spaghetti with cheese.","e1t":"Peynirli spagettiyi çok severim.","e2":"A bowl of spaghetti.","e2t":"Bir kase spagetti."},{"w":"speak","tr":"konuşmak","te":"Verb","tt":"Fiil","de":"To say words in order to communicate","dt":"İletişim kurmak için kelimeler söylemek","e1":"Can you speak English?","e1t":"İngilizce konuşabiliyor musun?","e2":"He speaks very slowly.","e2t":"O çok yavaş konuşuyor."},{"w":"spoon","tr":"kaşık","te":"Noun","tt":"İsim","de":"A tool with a shallow bowl used for eating soup","dt":"Çorba içmek için kullanılan sığ hazneli bir alet","e1":"I need a spoon for my soup.","e1t":"Çorbam için bir kaşığa ihtiyacım var.","e2":"Stir the tea with a spoon.","e2t":"Çayı bir kaşıkla karıştır."},{"w":"sport","tr":"spor","te":"Noun","tt":"İsim","de":"Physical activity for exercise or fun","dt":"Egzersiz veya eğlence için yapılan fiziksel aktivite","e1":"My favorite sport is football.","e1t":"En sevdiğim spor futboldur.","e2":"Do you play any sports?","e2t":"Herhangi bir spor yapıyor musun?"},{"w":"squirrel","tr":"sincap","te":"Noun","tt":"İsim","de":"A small animal with a long tail that eats nuts","dt":"Kuruyemiş yiyen, uzun kuyruklu küçük hayvan","e1":"The squirrel is climbing the tree.","e1t":"Sincap ağaca tırmanıyor.","e2":"Gray squirrel.","e2t":"Gri sincap."},{"w":"stairs","tr":"merdiven (bina içi)","te":"Noun","tt":"İsim (Plural)","de":"Steps to go up or down in a building","dt":"Bina içindeki basamaklar","e1":"Walk up the stairs.","e1t":"Merdivenlerden yukarı çık.","e2":"Dangerous stairs.","e2t":"Tehlikeli merdivenler."},{"w":"stand","tr":"ayakta durmak","te":"Verb","tt":"Fiil","de":"To be in a vertical position on one's feet","dt":"Ayakları üzerinde dikey konumda olmak","e1":"Don't stand near the door.","e1t":"Kapının yanında durma.","e2":"I have to stand on the bus.","e2t":"Otobüste ayakta durmak zorundayım."},{"w":"star","tr":"yıldız","te":"Noun","tt":"İsim","de":"A point of light in the night sky","dt":"Gece gökyüzündeki ışık noktası","e1":"We can see many stars tonight.","e1t":"Bu gece birçok yıldız görebiliyoruz.","e2":"He is looking at the stars.","e2t":"Yıldızlara bakıyor."},{"w":"start","tr":"başlamak","te":"Verb","tt":"Fiil","de":"To begin to do or happen","dt":"Yapmaya veya olmaya başlamak","e1":"The lesson starts at 9:00.","e1t":"Ders saat 9:00'da başlıyor.","e2":"Let's start the game.","e2t":"Hadi oyuna başlayalım."},{"w":"station","tr":"istasyon","te":"Noun","tt":"İsim","de":"A place where trains or buses stop","dt":"Tren veya otobüslerin durduğu yer","e1":"I am waiting for you at the station.","e1t":"Seni istasyonda bekliyorum.","e2":"Where is the nearest train station?","e2t":"En yakın tren istasyonu nerede?"},{"w":"sticker","tr":"çıkartma / etiket","te":"Noun","tt":"İsim","de":"A piece of paper that is sticky on one side","dt":"Bir yüzü yapışkanlı kağıt parçası","e1":"Put a sticker on your notebook.","e1t":"Defterine bir çıkartma yapıştır.","e2":"Colorful sticker.","e2t":"Renkli çıkartma."},{"w":"still","tr":"hâlâ","te":"Adverb","tt":"Zarf","de":"Continuing until now","dt":"Şimdiye kadar devam eden","e1":"I am still waiting for you.","e1t":"Hâlâ seni bekliyorum.","e2":"Is it still raining?","e2t":"Hâlâ yağmur mu yağıyor?"},{"w":"stomach","tr":"mide","te":"Noun","tt":"İsim","de":"The organ where food is digested","dt":"Yiyeceklerin sindirildiği organ","e1":"My stomach is empty.","e1t":"Midem boş.","e2":"I have a stomachache.","e2t":"Midem ağrıyor."},{"w":"stop","tr":"durmak / durdurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To end movement","dt":"Hareketi bitirmek","e1":"Stop the car.","e1t":"Arabayı durdur.","e2":"Bus stop.","e2t":"Otobüs durağı."},{"w":"storm","tr":"fırtına","te":"Noun","tt":"İsim","de":"Very bad weather with strong winds and rain","dt":"Güçlü rüzgarlar ve yağmurla birlikte çok kötü hava","e1":"There was a big storm last night.","e1t":"Dün gece büyük bir fırtına vardı.","e2":"Stay inside during the storm.","e2t":"Fırtına sırasında içeride kal."},{"w":"stormy","tr":"fırtınalı","te":"Adjective","tt":"Sıfat","de":"Characterized by a storm","dt":"Bir fırtına ile karakterize edilen","e1":"The sea is stormy tonight.","e1t":"Bu gece deniz fırtınalı.","e2":"It was a dark and stormy night.","e2t":"Karanlık ve fırtınalı bir geceydi."},{"w":"story","tr":"hikâye","te":"Noun","tt":"İsim","de":"A description of imaginary or real people","dt":"Hayali veya gerçek insanların anlatımı","e1":"Tell me a bedtime story.","e1t":"Bana bir uyku öncesi hikayesi anlat.","e2":"This is a true story.","e2t":"Bu gerçek bir hikaye."},{"w":"strawberry","tr":"çilek","te":"Noun","tt":"İsim","de":"A small red fruit with tiny seeds on its surface","dt":"Yüzeyinde küçük çekirdekleri olan küçük kırmızı bir meyve","e1":"I love strawberry ice cream.","e1t":"Çilekli dondurmaya bayılırım.","e2":"We picked fresh strawberries.","e2t":"Taze çilekler topladık."},{"w":"street","tr":"sokak","te":"Noun","tt":"İsim","de":"A public road in a city or town","dt":"Şehir veya kasabadaki halka açık yol","e1":"I live on this street.","e1t":"Bu sokakta yaşıyorum.","e2":"The street is very noisy.","e2t":"Sokak çok gürültülü."},{"w":"student","tr":"öğrenci","te":"Noun","tt":"İsim","de":"A person who is studying at a school","dt":"Bir okulda eğitim gören kişi","e1":"She is a university student.","e1t":"O bir üniversite öğrencisi.","e2":"The students are in the classroom.","e2t":"Öğrenciler sınıftalar."},{"w":"study","tr":"ders çalışmak","te":"Verb","tt":"Fiil","de":"To spend time learning about a subject","dt":"Bir konu hakkında öğrenmek için zaman harcamak","e1":"I study English every day.","e1t":"Her gün İngilizce çalışırım.","e2":"She is studying for her exam.","e2t":"O sınavı için çalışıyor."},{"w":"sugar","tr":"şeker","te":"Noun","tt":"İsim","de":"A sweet substance used to flavor food and drinks","dt":"Yiyecek ve içeceklere tat vermek için kullanılan tatlı madde","e1":"Don't put too much sugar in my tea.","e1t":"Çayıma çok fazla şeker koyma.","e2":"Sugar is bad for your teeth.","e2t":"Şeker dişlerin için kötüdür."},{"w":"summer","tr":"yaz","te":"Noun","tt":"İsim","de":"The hottest season of the year","dt":"Yılın en sıcak mevsimi","e1":"We go to the beach in summer.","e1t":"Yazın plaja gideriz.","e2":"Summer is my favorite season.","e2t":"Yaz en sevdiğim mevsimdir."},{"w":"sun","tr":"güneş","te":"Noun","tt":"İsim","de":"The star that gives light and heat to the earth","dt":"Dünyaya ışık ve ısı veren yıldız","e1":"The sun is shining today.","e1t":"Bugün güneş parlıyor.","e2":"Don't look directly at the sun.","e2t":"Güneşe doğrudan bakma."},{"w":"sunday","tr":"Pazar","te":"Noun","tt":"İsim","de":"The second day of the weekend","dt":"Hafta sonunun ikinci günü","e1":"Sunday is for resting.","e1t":"Pazar günü dinlenmek içindir.","e2":"We go to the park on Sunday.","e2t":"Pazar günü parka gideriz."},{"w":"sunglasses","tr":"güneş gözlüğü","te":"Noun","tt":"İsim","de":"Dark glasses that protect your eyes from the sun","dt":"Gözleri güneşten koruyan koyu renkli gözlükler","e1":"I need my sunglasses, it's very bright.","e1t":"Güneş gözlüğüme ihtiyacım var, hava çok parlak.","e2":"Where are my sunglasses?","e2t":"Güneş gözlüğüm nerede?"},{"w":"sunlight","tr":"gün ışığı","te":"Noun","tt":"İsim","de":"Light from the sun","dt":"Güneşten gelen ışık","e1":"I love natural sunlight.","e1t":"Doğal gün ışığını severim.","e2":"Sunlight is good for plants.","e2t":"Gün ışığı bitkiler için iyidir."},{"w":"sunny","tr":"güneşli","te":"Adjective","tt":"Sıfat","de":"Bright with sunlight","dt":"Gün ışığıyla parlak","e1":"I love sunny Sundays.","e1t":"Güneşli pazar günlerini severim.","e2":"The weather is sunny today.","e2t":"Bugün hava güneşli."},{"w":"support","tr":"destek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Help or encouragement given to someone","dt":"Birine verilen yardım veya teşvik","e1":"Thank you for your support.","e1t":"Desteğiniz için teşekkür ederim.","e2":"My family supports me.","e2t":"Ailem beni destekliyor."},{"w":"sweet","tr":"tatlı / şekerleme","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Tasting like sugar; or a small piece of candy","dt":"Şeker tadında olan; veya küçük şekerleme","e1":"This cake is very sweet.","e1t":"Bu kek çok tatlı.","e2":"Buy some sweets.","e2t":"Biraz şekerleme al."},{"w":"swimming","tr":"yüzme","te":"Noun","tt":"İsim","de":"The activity of moving through water","dt":"Suda hareket etme aktivitesi","e1":"I go swimming in the pool.","e1t":"Havuzda yüzmeye giderim.","e2":"Swimming is good for health.","e2t":"Yüzme sağlık için iyidir."},{"w":"t","tr":"shirt","te":"tişört","tt":"Noun","de":"İsim","dt":"A casual cotton shirt with short sleeves","e1":"Kısa kollu, günlük pamuklu bluz","e1t":"I wear a T","e2":"shirt in summer.","e2t":"Yazın tişört giyerim."},{"w":"table","tr":"masa","te":"Noun","tt":"İsim","de":"A piece of furniture with a flat top and legs","dt":"Düz bir üstü ve ayakları olan bir mobilya","e1":"Put the books on the table.","e1t":"Kitapları masanın üzerine koy.","e2":"We sit around the kitchen table.","e2t":"Mutfak masasının etrafında oturuyoruz."},{"w":"tail","tr":"kuyruk","te":"Noun","tt":"İsim","de":"The part at the back of an animal","dt":"Hayvanın arkasındaki parça","e1":"The dog is wagging its tail.","e1t":"Köpek kuyruğunu sallıyor.","e2":"A long tail.","e2t":"Uzun bir kuyruk."},{"w":"take","tr":"almak","te":"Verb","tt":"Fiil","de":"To get hold of something and move it","dt":"Bir şeyi tutup hareket ettirmek/almak","e1":"Take an umbrella with you.","e1t":"Yanına bir şemsiye al.","e2":"Can you take a photo of us?","e2t":"Bizim bir fotoğrafımızı çekebilir misin (alabilir misin)?"},{"w":"tall","tr":"uzun boylu","te":"Adjective","tt":"Sıfat","de":"Measuring a great distance from bottom to top","dt":"Aşağıdan yukarıya büyük bir mesafe ölçen","e1":"He is a tall man.","e1t":"O uzun boylu bir adamdır.","e2":"There are tall trees in the park.","e2t":"Parkta uzun ağaçlar var."},{"w":"taxi","tr":"taksi","te":"Noun","tt":"İsim","de":"A car with a driver that you pay to take you","dt":"Sizi götürmesi için ödeme yaptığınız şoförlü araba","e1":"Let's call a taxi.","e1t":"Haydi bir taksi çağıralım.","e2":"The taxi is waiting outside.","e2t":"Taksi dışarıda bekliyor."},{"w":"tea","tr":"çay","te":"Noun","tt":"İsim","de":"A popular hot drink made from dried leaves","dt":"Kurutulmuş yapraklardan yapılan popüler bir sıcak içecek","e1":"Turkish people love drinking tea.","e1t":"Türkler çay içmeyi çok sever.","e2":"Would you like some tea?","e2t":"Biraz çay ister misin?"},{"w":"teacher","tr":"öğretmen","te":"Noun","tt":"İsim","de":"A person who teaches students","dt":"Öğrencilere ders anlatan/öğreten kişi","e1":"My English teacher is very kind.","e1t":"İngilizce öğretmenim çok nazik.","e2":"He is a math teacher.","e2t":"O bir matematik öğretmeni."},{"w":"team","tr":"takım","te":"Noun","tt":"İsim","de":"A group of people who play a sport or work together","dt":"Birlikte spor yapan veya çalışan insan grubu","e1":"Our team won the match.","e1t":"Takımımız maçı kazandı.","e2":"I like working in a team.","e2t":"Takım halinde çalışmayı severim."},{"w":"teapot","tr":"çaydanlık","te":"Noun","tt":"İsim","de":"A container with a lid and a spout for making tea","dt":"Çay demlemek için kullanılan kapaklı ve emzikli kap","e1":"The teapot is on the table.","e1t":"Çaydanlık masanın üzerinde.","e2":"Ceramic teapot.","e2t":"Seramik çaydanlık."},{"w":"teddy","tr":"oyuncak ayı","te":"Noun","tt":"İsim","de":"A soft toy bear","dt":"Yumuşak oyuncak ayı","e1":"The baby is sleeping with a teddy.","e1t":"Bebek bir oyuncak ayıyla uyuyor.","e2":"Teddy bear.","e2t":"Oyuncak ayı."},{"w":"tennis","tr":"tenis","te":"Noun","tt":"İsim","de":"A game played with rackets and a small ball","dt":"Raket ve küçük bir topla oynanan oyun","e1":"Let's play tennis this afternoon.","e1t":"Bu öğleden sonra tenis oynayalım.","e2":"Tennis is a difficult sport.","e2t":"Tenis zor bir spordur."},{"w":"text","tr":"metin","te":"Noun","tt":"İsim","de":"The written words in a book or message","dt":"Bir kitap veya mesajdaki yazılı kelimeler","e1":"Read the text and answer the questions.","e1t":"Metni oku ve soruları cevapla.","e2":"Send me a text message.","e2t":"Bana bir kısa mesaj (metin) gönder."},{"w":"than","tr":"...den / ...dan","te":"Conjunction","tt":"Bağlaç","de":"Used for comparisons","dt":"Karşılaştırmalar için kullanılır","e1":"He is taller than me.","e1t":"O benden daha uzun.","e2":"This book is better than that one.","e2t":"Bu kitap şundan daha iyi."},{"w":"thanks","tr":"teşekkürler","te":"Noun/Exclamation","tt":"İsim/Ünlem","de":"Used to express gratitude","dt":"Minnettarlık ifade etmek için kullanılır","e1":"Thanks for your help.","e1t":"Yardımın için teşekkürler.","e2":"Many thanks!","e2t":"Çok teşekkürler!"},{"w":"then","tr":"o zaman / sonra","te":"Adverb","tt":"Zarf","de":"At that time or after that","dt":"O vakitte veya ondan sonra","e1":"First wash your hands, then eat.","e1t":"Önce ellerini yıka, sonra ye.","e2":"If you are tired, then sleep.","e2t":"Eğer yorgunsan, o zaman uyu."},{"w":"third","tr":"üçüncü","te":"Ordinal Number","tt":"Sıra Numarası","de":"Number three in a sequence","dt":"Sıralamada üç numara","e1":"My office is on the third floor.","e1t":"Ofisim üçüncü katta.","e2":"Today is her third birthday.","e2t":"Bugün onun üçüncü doğum günü."},{"w":"thursday","tr":"Perşembe","te":"Noun","tt":"İsim","de":"The fourth day of the work week","dt":"Çalışma haftasının dördüncü günü","e1":"I visit my parents on Thursday.","e1t":"Perşembe günü ailemi ziyaret ederim.","e2":"Is the shop open on Thursday?","e2t":"Dükkan Perşembe günü açık mı?"},{"w":"tired","tr":"yorgun","te":"Adjective","tt":"Sıfat","de":"Needing rest or sleep","dt":"Dinlenmeye veya uyumaya ihtiyaç duyma","e1":"I am very tired after work.","e1t":"İşten sonra çok yorgunum.","e2":"You look tired, go to sleep.","e2t":"Yorgun görünüyorsun, git uyu."},{"w":"to","tr":"...e / ...a","te":"Preposition","tt":"Edat","de":"Expressing motion in the direction of","dt":"... yönünde hareketi ifade eden","e1":"I am going to the school.","e1t":"Okula gidiyorum.","e2":"Give the book to him.","e2t":"Kitabı ona ver."},{"w":"toaster","tr":"ekmek kızartma makinesi","te":"Noun","tt":"İsim","de":"A machine that makes bread brown and crisp","dt":"Ekmeği kızartan makine","e1":"Put the bread in the toaster.","e1t":"Ekmeği kızartma makinesine koy.","e2":"Kitchen toaster.","e2t":"Mutfak tost makinesi."},{"w":"today","tr":"bugün","te":"Noun","tt":"İsim","de":"On this present day","dt":"Bu mevcut günde","e1":"Today is my birthday.","e1t":"Bugün benim doğum günüm.","e2":"What is the date today?","e2t":"Bugünün tarihi ne?"},{"w":"tomato","tr":"domates","te":"Noun","tt":"İsim","de":"A red round fruit often used as a vegetable","dt":"Genellikle sebze olarak kullanılan kırmızı yuvarlak meyve","e1":"I put tomato in the salad.","e1t":"Salataya domates koydum.","e2":"Tomato soup is delicious.","e2t":"Domates çorbası lezzetlidir."},{"w":"tomorrow","tr":"yarın","te":"Noun","tt":"İsim","de":"On the day after today","dt":"Bugünden sonraki günde","e1":"Tomorrow will be sunny.","e1t":"Yarın hava güneşli olacak.","e2":"See you tomorrow!","e2t":"Yarın görüşürüz!"},{"w":"tooth","tr":"diş","te":"Noun","tt":"İsim","de":"Hard white objects in the mouth used for biting","dt":"Ağızdaki ısırmak için kullanılan sert beyaz nesneler","e1":"Brush your teeth twice a day.","e1t":"Dişlerini günde iki kez fırçala.","e2":"I have a toothache.","e2t":"Dişim ağrıyor."},{"w":"toothbrush","tr":"diş fırçası","te":"Noun","tt":"İsim","de":"A small brush for cleaning teeth","dt":"Diş temizlemek için küçük fırça","e1":"Where is my toothbrush?","e1t":"Diş fırçam nerede?","e2":"Use your toothbrush.","e2t":"Diş fırçanı kullan."},{"w":"toothpaste","tr":"diş macunu","te":"Noun","tt":"İsim","de":"A substance used with a brush to clean teeth","dt":"Dişleri temizlemek için fırçayla kullanılan madde","e1":"I need some toothpaste.","e1t":"Biraz diş macununa ihtiyacım var.","e2":"Mint toothpaste.","e2t":"Naneli diş macunu."},{"w":"tortoise","tr":"kaplumbağa (kara)","te":"Noun","tt":"İsim","de":"An animal with a thick shell that moves slowly","dt":"Yavaş hareket eden, kalın kabuklu hayvan","e1":"The tortoise is eating lettuce.","e1t":"Kaplumbağa marul yiyor.","e2":"Slow tortoise.","e2t":"Yavaş kaplumbağa."},{"w":"touch","tr":"dokunmak","te":"Verb","tt":"Fiil","de":"To put your hand on something","dt":"Elini bir şeyin üzerine koymak","e1":"Don't touch the wet paint.","e1t":"Islak boyaya dokunma.","e2":"The baby touched my face.","e2t":"Bebek yüzüme dokundu."},{"w":"town","tr":"kasaba","te":"Noun","tt":"İsim","de":"A place where people live, smaller than a city","dt":"Şehirden küçük yerleşim yeri","e1":"It is a small and quiet town.","e1t":"Küçük ve sessiz bir kasaba.","e2":"My grandparents live in a town.","e2t":"Büyükbabamlar bir kasabada yaşıyor."},{"w":"train","tr":"tren","te":"Noun","tt":"İsim","de":"A series of connected railway carriages","dt":"Birbirine bağlı demiryolu vagonları serisi","e1":"The train arrives at the station.","e1t":"Tren istasyona varıyor.","e2":"I like traveling by train.","e2t":"Trenle seyahat etmeyi severim."},{"w":"travel","tr":"seyahat etmek","te":"Verb","tt":"Fiil","de":"To go from one place to another","dt":"Bir yerden başka bir yere gitmek","e1":"I want to travel the world.","e1t":"Dünyayı gezmek istiyorum.","e2":"They travel by train.","e2t":"Trenle seyahat ediyorlar."},{"w":"trip","tr":"gezi / yolculuk / çelme takmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A journey or excursion; or to stumble","dt":"Bir yerden bir yere gidiş; veya ayağı takılmak","e1":"Have a nice trip!","e1t":"İyi yolculuklar!","e2":"A school trip.","e2t":"Okul gezisi."},{"w":"tuesday","tr":"Salı","te":"Noun","tt":"İsim","de":"The second day of the work week","dt":"Çalışma haftasının ikinci günü","e1":"We have a meeting on Tuesday.","e1t":"Salı günü toplantımız var.","e2":"Are you free on Tuesday?","e2t":"Salı günü müsait misin?"},{"w":"turnip","tr":"şalgam","te":"Noun","tt":"İsim","de":"A round root with white or cream flesh which is eaten as a vegetable","dt":"Sebze olarak yenen yuvarlak kök","e1":"I don't like turnips.","e1t":"Şalgam sevmem.","e2":"Turnip juice.","e2t":"Şalgam suyu."},{"w":"tv","tr":"televizyon","te":"Noun","tt":"İsim","de":"Short for television","dt":"Televizyon kelimesinin kısaltması","e1":"What is on TV tonight?","e1t":"Bu gece TV'de ne var?","e2":"Don't watch too much TV.","e2t":"Çok fazla TV izleme."},{"w":"ugly","tr":"çirkin","te":"Adjective","tt":"Sıfat","de":"Unpleasant or repulsive in appearance","dt":"Görünüşte hoş olmayan veya itici","e1":"This is an ugly painting.","e1t":"Bu çirkin bir tablo.","e2":"There are no ugly animals.","e2t":"Çirkin hayvan yoktur."},{"w":"umbrella","tr":"şemsiye","te":"Noun","tt":"İsim","de":"A folding device used for protection from rain","dt":"Yağmurdan korunmak için kullanılan katlanır cihaz","e1":"Don't forget your umbrella.","e1t":"Şemsiyeni unutma.","e2":"Can I share your umbrella?","e2t":"Şemsiyeni paylaşabilir miyiz?"},{"w":"under","tr":"altında","te":"Preposition","tt":"Edat","de":"Below or at a lower level than","dt":"Bir şeyin altında veya daha alt seviyesinde","e1":"My bag is under the table.","e1t":"Çantam masanın altında.","e2":"The cat is sleeping under the bed.","e2t":"Kedi yatağın altında uyuyor."},{"w":"understand","tr":"anlamak","te":"Verb","tt":"Fiil","de":"To know the meaning of what someone says","dt":"Birinin söylediği şeyin anlamını bilmek","e1":"I don't understand this question.","e1t":"Bu soruyu anlamıyorum.","e2":"Do you understand me?","e2t":"Beni anlıyor musun?"},{"w":"upstairs","tr":"üst kat / yukarıda","te":"Adverb/Adjective/Noun","tt":"On or to an upper floor of a building","de":"Bir binanın daha yukarıdaki katında","dt":"Go upstairs.","e1":"Yukarı (üst kata) çık.","e1t":"The bedroom is upstairs.","e2":"Yatak odası üst kattadır.","e2t":""},{"w":"use","tr":"kullanmak","te":"Verb","tt":"Fiil","de":"To do something with a tool or object","dt":"Bir araç veya nesne ile bir şey yapmak","e1":"Can I use your pen?","e1t":"Kalemini kullanabilir miyim?","e2":"I use the computer for work.","e2t":"Bilgisayarı iş için kullanırım."},{"w":"usually","tr":"genellikle","te":"Adverb","tt":"Zarf","de":"Under normal conditions; generally","dt":"Normal koşullar altında; genelde","e1":"I usually have bread for breakfast.","e1t":"Kahvaltıda genellikle ekmek yerim.","e2":"He usually goes to bed late.","e2t":"O genellikle geç yatar."},{"w":"vegetable","tr":"sebze","te":"Noun","tt":"İsim","de":"A plant or part of a plant used as food","dt":"Yemek olarak kullanılan bir bitki veya bitki parçası","e1":"You should eat more vegetables.","e1t":"Daha fazla sebze yemelisin.","e2":"Green vegetables are good.","e2t":"Yeşil sebzeler iyidir."},{"w":"very","tr":"çok","te":"Adverb","tt":"Zarf","de":"To a high degree","dt":"Yüksek derecede","e1":"It is very cold today.","e1t":"Bugün hava çok soğuk.","e2":"Thank you very much.","e2t":"Çok teşekkür ederim."},{"w":"wait","tr":"beklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stay in one place until something happens","dt":"Bir şey olana kadar bir yerde durmak","e1":"Wait for me!","e1t":"Beni bekle!","e2":"A long wait.","e2t":"Uzun bir bekleyiş."},{"w":"waiter","tr":"garson","te":"Noun","tt":"İsim","de":"A person who serves food in a restaurant","dt":"Restoranda yemek servis eden kişi","e1":"The waiter brought the menu.","e1t":"Garson menüyü getirdi.","e2":"We gave a tip to the waiter.","e2t":"Garsona bahşiş verdik."},{"w":"walk","tr":"yürümek","te":"Verb","tt":"Fiil","de":"To move on foot at a regular pace","dt":"Düzenli bir hızda yaya olarak hareket etmek","e1":"I walk in the park every morning.","e1t":"Her sabah parkta yürürüm.","e2":"We can walk to the school.","e2t":"Okula yürüyebiliriz."},{"w":"wall","tr":"duvar","te":"Noun","tt":"İsim","de":"A vertical structure that forms the side of a room","dt":"Bir odanın kenarını oluşturan dikey yapı","e1":"There is a picture on the wall.","e1t":"Duvarda bir resim var.","e2":"The walls are painted white.","e2t":"Duvarlar beyaza boyanmış."},{"w":"wallet","tr":"cüzdan","te":"Noun","tt":"İsim","de":"A small flat case for carrying money","dt":"Para taşımak için küçük düz çanta/kılıf","e1":"I lost my wallet yesterday.","e1t":"Dün cüzdanımı kaybettim.","e2":"There is no money in my wallet.","e2t":"Cüzdanımda hiç para yok."},{"w":"want","tr":"istemek","te":"Verb","tt":"Fiil","de":"To have a desire or wish for something","dt":"Bir şeye karşı arzu veya istek duymak","e1":"I want to drink some water.","e1t":"Biraz su içmek istiyorum.","e2":"What do you want for dinner?","e2t":"Akşam yemeği için ne istersin?"},{"w":"warm","tr":"ılık","te":"Adjective","tt":"Sıfat","de":"At a fairly high temperature in a pleasant way","dt":"Hoş bir şekilde oldukça yüksek sıcaklıkta","e1":"The milk is warm enough.","e1t":"Süt yeterince ılık.","e2":"I like warm weather.","e2t":"Ilık havayı severim."},{"w":"watch","tr":"izlemek","te":"Verb","tt":"Fiil","de":"To look at something for a period of time","dt":"Bir şeye belli bir süre boyunca bakmak","e1":"I watch TV in the evening.","e1t":"Akşamları TV izlerim.","e2":"Do you want to watch a movie?","e2t":"Film izlemek ister misin?"},{"w":"water","tr":"su","te":"Noun","tt":"İsim","de":"A clear liquid that falls as rain","dt":"Yağmur olarak düşen berrak sıvı","e1":"Can I have a glass of water?","e1t":"Bir bardak su alabilir miyim?","e2":"Drink plenty of water.","e2t":"Bol bol su iç."},{"w":"watermelon","tr":"karpuz","te":"Noun","tt":"İsim","de":"A large fruit with a hard green rind and sweet watery red flesh with black seeds","dt":"Sert yeşil kabuklu, sulu ve tatlı kırmızı meyve","e1":"We eat watermelon in summer.","e1t":"Yazın karpuz yeriz.","e2":"Sweet watermelon.","e2t":"Tatlı karpuz."},{"w":"way","tr":"yol / yöntem","te":"Noun","tt":"İsim","de":"A route or a method of doing something","dt":"Bir rota veya bir şeyi yapma yöntemi","e1":"Can you tell me the way to the bank?","e1t":"Bana bankaya giden yolu söyleyebilir misin?","e2":"This is the right way.","e2t":"Doğru yol burası."},{"w":"website","tr":"web sitesi","te":"Noun","tt":"İsim","de":"A set of pages on the internet","dt":"İnternet üzerindeki sayfalar seti","e1":"Visit our website for more information.","e1t":"Daha fazla bilgi için web sitemizi ziyaret edin.","e2":"What is your favorite website?","e2t":"En sevdiğin web sitesi hangisi?"},{"w":"wednesday","tr":"Çarşamba","te":"Noun","tt":"İsim","de":"The third day of the work week","dt":"Çalışma haftasının üçüncü günü","e1":"The exam is on Wednesday.","e1t":"Sınav Çarşamba günü.","e2":"Wednesday is the middle of the week.","e2t":"Çarşamba haftanın ortasıdır."},{"w":"week","tr":"hafta","te":"Noun","tt":"İsim","de":"A period of seven days","dt":"Yedi günlük zaman dilimi","e1":"There are seven days in a week.","e1t":"Bir haftada yedi gün vardır.","e2":"I see my friends every week.","e2t":"Arkadaşlarımı her hafta görürüm."},{"w":"west","tr":"batı","te":"Noun","tt":"İsim","de":"The direction where the sun sets","dt":"Güneşin battığı yön","e1":"Izmir is in the west of Turkey.","e1t":"İzmir Türkiye'nin batısındadır.","e2":"We are traveling to the west.","e2t":"Batıya seyahat ediyoruz."},{"w":"what","tr":"ne","te":"Pronoun/Adjective","tt":"Zamir/Sıfat","de":"Asking for information about something","dt":"Bir şey hakkında bilgi sorma","e1":"What is your name?","e1t":"Adın ne?","e2":"What are you doing?","e2t":"Ne yapıyorsun?"},{"w":"when","tr":"ne zaman","te":"Adverb/Conjunction","tt":"Zarf/Bağlaç","de":"At what time","dt":"Hangi zamanda","e1":"When is your birthday?","e1t":"Doğum günün ne zaman?","e2":"When does the train leave?","e2t":"Tren ne zaman kalkıyor?"},{"w":"where","tr":"nerede","te":"Adverb/Pronoun","tt":"Zarf/Zamir","de":"At or in what place","dt":"Hangi yerde veya konumda","e1":"Where is my bag?","e1t":"Çantam nerede?","e2":"Where do you live?","e2t":"Nerede yaşıyorsun?"},{"w":"which","tr":"hangi","te":"Pronoun/Adjective","tt":"Zamir/Sıfat","de":"Asking about a specific choice","dt":"Belirli bir seçenek hakkında sorma","e1":"Which color do you like?","e1t":"Hangi rengi seviyorsun?","e2":"Which bus goes to the city?","e2t":"Şehre hangi otobüs gider?"},{"w":"white","tr":"beyaz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of milk or snow","dt":"Sütün veya karın rengi","e1":"Snow is white.","e1t":"Kar beyazdır.","e2":"I want a white shirt.","e2t":"Beyaz bir gömlek istiyorum."},{"w":"who","tr":"kim","te":"Pronoun","tt":"Zamir","de":"What or which person","dt":"Hangi kişi","e1":"Who is that man?","e1t":"Şu adam kim?","e2":"Who are your friends?","e2t":"Arkadaşların kim?"},{"w":"why","tr":"neden","te":"Adverb","tt":"Zarf","de":"For what reason","dt":"Hangi sebeple","e1":"Why are you crying?","e1t":"Neden ağlıyorsun?","e2":"Why is the shop closed?","e2t":"Dükkan neden kapalı?"},{"w":"wife","tr":"eş (kadın)","te":"Noun","tt":"İsim","de":"The woman that a man is married to","dt":"Bir adamın evli olduğu kadın","e1":"His wife is a teacher.","e1t":"Eşi bir öğretmendir.","e2":"He bought a gift for his wife.","e2t":"Eşi için bir hediye aldı."},{"w":"window","tr":"pencere","te":"Noun","tt":"İsim","de":"An opening in a wall to let in light and air","dt":"Işık ve hava girmesi için duvardaki açıklık","e1":"Open the window, it's hot.","e1t":"Pencereyi aç, hava sıcak.","e2":"I can see the garden from the window.","e2t":"Pencereden bahçeyi görebiliyorum."},{"w":"winter","tr":"kış","te":"Noun","tt":"İsim","de":"The coldest season of the year","dt":"Yılın en soğuk mevsimi","e1":"I like winter sports.","e1t":"Kış sporlarını severim.","e2":"We wear heavy coats in winter.","e2t":"Kışın kalın montlar giyeriz."},{"w":"with","tr":"ile","te":"Preposition","tt":"Edat","de":"Accompanied by","dt":"Eşliğinde","e1":"I live with my family.","e1t":"Ailemle birlikte yaşıyorum.","e2":"Coffee with milk, please.","e2t":"Sütlü (süt ile) kahve lütfen."},{"w":"without","tr":"...sız / ...siz","te":"Preposition","tt":"Edat","de":"Not having or including something","dt":"Bir şeye sahip olmadan veya dahil etmeden","e1":"I can't see without my glasses.","e1t":"Gözlüklerim olmadan göremem.","e2":"He left without saying goodbye.","e2t":"Hoşça kal demeden ayrıldı."},{"w":"woman","tr":"kadın","te":"Noun","tt":"İsim","de":"An adult female human","dt":"Yetişkin kadın insan","e1":"A woman is waiting for you.","e1t":"Bir kadın seni bekliyor.","e2":"She is a strong woman.","e2t":"O güçlü bir kadındır."},{"w":"word","tr":"kelime","te":"Noun","tt":"İsim","de":"A single distinct meaningful element of speech","dt":"Konuşmanın anlamlı tek bir öğesi","e1":"What does this word mean?","e1t":"Bu kelime ne anlama geliyor?","e2":"I don't know that word.","e2t":"O kelimeyi bilmiyorum."},{"w":"work","tr":"iş / çalışmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Activity involving mental or physical effort","dt":"Zihinsel veya fiziksel çaba gerektiren aktivite","e1":"I go to work at 8 AM.","e1t":"Sabah 8'de işe giderim.","e2":"He works in a big company.","e2t":"O büyük bir şirkette çalışıyor."},{"w":"worker","tr":"işçi","te":"Noun","tt":"İsim","de":"A person who does a job to earn money","dt":"Para kazanmak için bir iş yapan kişi","e1":"The factory has many workers.","e1t":"Fabrikanın birçok işçisi var.","e2":"He is a hard worker.","e2t":"O çalışkan bir işçidir."},{"w":"world","tr":"dünya","te":"Noun","tt":"İsim","de":"The earth and all the people on it","dt":"Dünya ve üzerindeki tüm insanlar","e1":"I want to travel around the world.","e1t":"Dünyayı gezmek istiyorum.","e2":"He is the famous person in the world.","e2t":"O dünyadaki en ünlü kişidir."},{"w":"write","tr":"yazmak","te":"Verb","tt":"Fiil","de":"To mark letters or words on a surface","dt":"Bir yüzey üzerine harfler veya kelimeler işaretlemek","e1":"Write your name here.","e1t":"İsmini buraya yaz.","e2":"I write a letter to my friend.","e2t":"Arkadaşıma bir mektup yazıyorum."},{"w":"year","tr":"yıl","te":"Noun","tt":"İsim","de":"A period of 365 days","dt":"365 günlük zaman dilimi","e1":"Happy New Year!","e1t":"Mutlu yıllar!","e2":"I was born in the year 2000.","e2t":"2000 yılında doğdum."},{"w":"yellow","tr":"sarı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color of lemons or the sun","dt":"Limonun veya güneşin rengi","e1":"The sun is a yellow star.","e1t":"Güneş sarı bir yıldızdır.","e2":"She is wearing a yellow hat.","e2t":"Sarı bir şapka takıyor."},{"w":"yes","tr":"evet","te":"Exclamation","tt":"Ünlem","de":"Used to give a positive response","dt":"Olumlu yanıt vermek için kullanılır","e1":"Yes, I can speak English.","e1t":"Evet, İngilizce konuşabiliyorum.","e2":"Yes, please.","e2t":"Evet, lütfen."},{"w":"yesterday","tr":"dün","te":"Noun","tt":"İsim","de":"On the day before today","dt":"Bugünden önceki günde","e1":"I saw him yesterday.","e1t":"Onu dün gördüm.","e2":"Yesterday was Sunday.","e2t":"Dün pazardı."},{"w":"yet","tr":"henüz","te":"Adverb","tt":"Zarf","de":"Up to now (used in negatives/questions)","dt":"Şimdiye kadar (olumsuz ve sorularda)","e1":"I haven't eaten yet.","e1t":"Henüz yemek yemedim.","e2":"Is the bus here yet?","e2t":"Otobüs henüz geldi mi?"},{"w":"young","tr":"genç","te":"Adjective","tt":"Sıfat","de":"Having lived for only a short time","dt":"Sadece kısa bir süredir yaşamış olan","e1":"She is a young teacher.","e1t":"O genç bir öğretmendir.","e2":"Young people like music.","e2t":"Gençler müziği sever."},{"w":"a2","tr":"","te":"","tt":"","de":"","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"ability","tr":"yetenek","te":"Noun","tt":"İsim","de":"The physical or mental power to do something","dt":"Bir şeyi yapmak için gereken fiziksel veya zihinsel güç","e1":"He has the ability to speak three languages.","e1t":"Üç dil konuşma yeteneği var.","e2":"She has a great musical ability.","e2t":"Harika bir müzik yeteneği var."},{"w":"abroad","tr":"yurtdışında","te":"Adverb","tt":"Zarf","de":"In or to a foreign country","dt":"Yabancı bir ülkede veya yabancı bir ülkeye","e1":"My brother is studying abroad.","e1t":"Erkek kardeşim yurtdışında okuyor.","e2":"I want to travel abroad this summer.","e2t":"Bu yaz yurtdışına seyahat etmek istiyorum."},{"w":"accident","tr":"kaza","te":"Noun","tt":"İsim","de":"Something bad that happens unexpectedly","dt":"Beklenmedik bir şekilde gerçekleşen kötü bir olay","e1":"He had a car accident yesterday.","e1t":"Dün bir trafik kazası geçirdi.","e2":"It was just an accident.","e2t":"Sadece bir kazaydı."},{"w":"accommodation","tr":"konaklama","te":"Noun","tt":"İsim","de":"A place to live, work, or stay in","dt":"Yaşanacak, çalışılacak veya kalınacak yer","e1":"Hotel accommodation is included in the price.","e1t":"Otel konaklaması fiyata dahildir.","e2":"We are looking for cheap accommodation.","e2t":"Ucuz konaklama arıyoruz."},{"w":"ache","tr":"ağrı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A continuous dull pain","dt":"Sürekli ve künt bir ağrı","e1":"My back aches.","e1t":"Sırtım ağrıyor.","e2":"I have an ache in my shoulder.","e2t":"Omuzumda bir ağrı var."},{"w":"achieve","tr":"başarmak","te":"Verb","tt":"Fiil","de":"To succeed in finishing or getting something","dt":"Bir şeyi bitirmeyi veya elde etmeyi başarmak","e1":"You can achieve anything if you work hard.","e1t":"Eğer sıkı çalışırsan her şeyi başarabilirsin.","e2":"She achieved her goal.","e2t":"Hedefini başardı."},{"w":"act","tr":"davranmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To behave in a particular way","dt":"Belirli bir şekilde davranmak","e1":"Stop acting like a child!","e1t":"Çocuk gibi davranmayı bırak!","e2":"He acted very bravely during the fire.","e2t":"Yangın sırasında çok cesurca davrandı."},{"w":"active","tr":"aktif","te":"Adjective","tt":"Sıfat","de":"Busy with a particular activity","dt":"Belirli bir aktiviteyle meşgul olma","e1":"He is an active person.","e1t":"O aktif bir insandır.","e2":"You should stay active for your health.","e2t":"Sağlığın için aktif kalmalısın."},{"w":"activity","tr":"etkinlik","te":"Noun","tt":"İsim","de":"Something that is done for enjoyment or work","dt":"Eğlence veya iş için yapılan bir şey","e1":"Swimming is my favorite activity.","e1t":"Yüzmek en sevdiğim etkinliktir.","e2":"There are many activities at the hotel.","e2t":"Otelde birçok etkinlik var."},{"w":"actually","tr":"aslında","te":"Adverb","tt":"Zarf","de":"Used to emphasize the real facts","dt":"Gerçek gerçekleri vurgulamak için kullanılır","e1":"I'm not actually Turkish.","e1t":"Aslında Türk değilim.","e2":"What did he actually say?","e2t":"Aslında ne söyledi?"},{"w":"admire","tr":"hayran olmak","te":"Verb","tt":"Fiil","de":"To respect and approve of someone","dt":"Biri saygı duymak ve onaylamak","e1":"I admire his hard work.","e1t":"Onun sıkı çalışmasına hayranım.","e2":"Many people admire her talent.","e2t":"Birçok kişi onun yeteneğine hayranlık duyuyor."},{"w":"admission","tr":"giriş izni","te":"Noun","tt":"İsim","de":"Permission to enter a place","dt":"Bir yere girme izni","e1":"Admission is free for children.","e1t":"Çocuklar için giriş ücretsizdir.","e2":"He made an admission of guilt.","e2t":"Suçunu itiraf etti (kabul etti)."},{"w":"adopt","tr":"evlat edinmek","te":"Verb","tt":"Fiil","de":"To legally take a child as one's own","dt":"Bir çocuğu yasal olarak kendi çocuğu gibi almak","e1":"They decided to adopt a baby.","e1t":"Bir bebek evlat edinmeye karar verdiler.","e2":"We adopted a cat from the shelter.","e2t":"Barınaktan bir kedi sahiplendik (evlat edindik)."},{"w":"advance","tr":"ilerlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move forward or a development","dt":"İleriye gitmek veya bir gelişme","e1":"Technology continues to advance.","e1t":"Teknoloji ilerlemeye devam ediyor.","e2":"We need an advance payment.","e2t":"Avans (önceden) ödemeye ihtiyacımız var."},{"w":"advert","tr":"ilan / reklam","te":"Noun","tt":"İsim","de":"A notice or announcement in a public medium promoting a product or service","dt":"Bir ürünü veya hizmeti tanıtan ilan veya duyuru","e1":"I saw an advert for a new car.","e1t":"Yeni bir araba ilanı gördüm.","e2":"Job advert.","e2t":"İş ilanı."},{"w":"advertise","tr":"reklam yapmak","te":"Verb","tt":"Fiil","de":"To promote goods or services","dt":"Mal veya hizmetlerin tanıtımını yapmak","e1":"They advertise their products on TV.","e1t":"Ürünlerinin reklamını TV'de yapıyorlar.","e2":"We need to advertise for a new manager.","e2t":"Yeni bir müdür için ilan (reklam) vermeliyiz."},{"w":"advertisement","tr":"reklam","te":"Noun","tt":"İsim","de":"A notice or film telling people about a product","dt":"İnsanlara bir ürünü anlatan ilan veya film","e1":"I saw an advertisement for a new car.","e1t":"Yeni bir araba reklamı gördüm.","e2":"Put an advertisement in the newspaper.","e2t":"Gazeteye bir ilan ver."},{"w":"advice","tr":"tavsiye","te":"Noun","tt":"İsim","de":"An opinion about what someone should do","dt":"Birinin ne yapması gerektiği konusundaki görüş","e1":"Can you give me some advice?","e1t":"Bana biraz tavsiye verebilir misin?","e2":"I need advice on buying a car.","e2t":"Araba alma konusunda tavsiyeye ihtiyacım var."},{"w":"advise","tr":"tavsiye etmek","te":"Verb","tt":"Fiil","de":"To give an opinion about what should be done","dt":"Ne yapılması gerektiği konusunda görüş bildirmek","e1":"My doctor advised me to lose weight.","e1t":"Doktorum kilo vermemi tavsiye etti.","e2":"Can you advise me on this?","e2t":"Bu konuda bana tavsiye verebilir misin?"},{"w":"affect","tr":"etkilemek","te":"Verb","tt":"Fiil","de":"To produce a change in someone or something","dt":"Birinde veya bir şeyde değişim yaratmak","e1":"The weather affects my mood.","e1t":"Hava durumu ruh halimi etkiliyor.","e2":"Smoking affects your health.","e2t":"Sigara içmek sağlığını etkiler."},{"w":"afford","tr":"karşılayabilmek","te":"Verb","tt":"Fiil","de":"To have enough money to buy something","dt":"Bir şeyi alacak kadar parası olmak","e1":"I can't afford to buy a new car.","e1t":"Yeni bir araba almayı karşılayamam (gücüm yetmez).","e2":"We can't afford a long holiday.","e2t":"Uzun bir tatili karşılayamayız."},{"w":"afraid","tr":"korkmuş","te":"Adjective","tt":"Sıfat","de":"Feeling fear or being worried","dt":"Korku hissetme veya endişeli olma","e1":"I am afraid of spiders.","e1t":"Örümceklerden korkarım.","e2":"Don't be afraid of mistakes.","e2t":"Hatalardan korkma."},{"w":"agency","tr":"ajans","te":"Noun","tt":"İsim","de":"A business that provides a service","dt":"Hizmet sağlayan bir işletme","e1":"He works for a travel agency.","e1t":"Bir seyahat acentesinde (ajansında) çalışıyor.","e2":"The agency found us a new house.","e2t":"Ajans bize yeni bir ev buldu."},{"w":"agenda","tr":"gündem","te":"Noun","tt":"İsim","de":"A list of items to be discussed at a meeting","dt":"Bir toplantıda tartışılacak maddeler listesi","e1":"What is on the agenda for today?","e1t":"Bugünün gündeminde ne var?","e2":"We have a busy agenda.","e2t":"Yoğun bir gündemimiz var."},{"w":"aggressive","tr":"saldırgan","te":"Adjective","tt":"Sıfat","de":"Ready or likely to attack or argue","dt":"Saldırmaya veya tartışmaya hazır/meyilli","e1":"He has an aggressive personality.","e1t":"Saldırgan bir kişiliği var.","e2":"Don't be so aggressive.","e2t":"Bu kadar saldırgan olma."},{"w":"agree","tr":"anlaşmak","te":"Verb","tt":"Fiil","de":"To have the same opinion as someone","dt":"Biriyle aynı görüşte olmak","e1":"I agree with you.","e1t":"Sana katılıyorum (seninle aynı fikirdeyim).","e2":"They agreed on the plan.","e2t":"Plan üzerinde anlaştılar."},{"w":"aid","tr":"yardım","te":"Noun/Verb","tt":"İsim/Fiil","de":"Help or support","dt":"Yardım veya destek","e1":"They sent medical aid to the region.","e1t":"Bölgeye tıbbi yardım gönderdiler.","e2":"He aided the police in the search.","e2t":"Aramada polise yardım etti."},{"w":"aim","tr":"amaç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A goal or result that you try to achieve","dt":"Başarmaya çalıştığınız bir hedef veya sonuç","e1":"My main aim is to finish school.","e1t":"Ana amacım okulu bitirmek.","e2":"He aimed the gun at the target.","e2t":"Silahı hedefe doğrulttu (amaçladı)."},{"w":"aircraft","tr":"uçak","te":"Noun","tt":"İsim","de":"A vehicle that can fly","dt":"Uçabilen araç","e1":"The aircraft landed safely.","e1t":"Uçak güvenli bir şekilde indi.","e2":"This is a military aircraft.","e2t":"Bu bir askeri uçaktır."},{"w":"alarm","tr":"alarm","te":"Noun/Verb","tt":"İsim/Fiil","de":"A warning sound or a feeling of fear","dt":"Uyarı sesi veya korku hissi","e1":"Set the alarm for 6 AM.","e1t":"Alarmı sabah 6'ya kur.","e2":"I felt a sense of alarm.","e2t":"Bir panik (alarm) hissettim."},{"w":"alcohol","tr":"alkol","te":"Noun","tt":"İsim","de":"Drinks such as wine or beer","dt":"Şarap veya bira gibi içecekler","e1":"Alcohol is not allowed here.","e1t":"Burada alkole izin verilmez.","e2":"He doesn't drink alcohol.","e2t":"Alkol kullanmaz."},{"w":"alive","tr":"canlı","te":"Adjective","tt":"Sıfat","de":"Living, not dead","dt":"Yaşayan, ölü olmayan","e1":"He is still alive.","e1t":"O hâlâ hayatta.","e2":"It's good to be alive.","e2t":"Hayatta olmak güzel."},{"w":"aloud","tr":"yüksek sesle","te":"Adverb","tt":"Zarf","de":"Not silently; in a voice that can be heard","dt":"Sessizce değil; duyulabilecek bir sesle","e1":"Please read the text aloud.","e1t":"Lütfen metni yüksek sesle oku.","e2":"Laugh aloud.","e2t":"Sesli gülmek."},{"w":"alter","tr":"değiştirmek","te":"Verb","tt":"Fiil","de":"To change something slightly","dt":"Bir şeyi hafifçe değiştirmek","e1":"We need to alter our plans.","e1t":"Planlarımızı değiştirmemiz gerekiyor.","e2":"She altered her dress.","e2t":"Elbisesini tadil etti (değiştirdi)."},{"w":"amazed","tr":"şaşırmış","te":"Adjective","tt":"Sıfat","de":"Very surprised","dt":"Çok şaşırmış","e1":"I was amazed by the view.","e1t":"Manzara karşısında şaşkına döndüm (hayran kaldım).","e2":"He looked amazed.","e2t":"Şaşırmış görünüyordu."},{"w":"amazing","tr":"şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Extremely surprising or good","dt":"Son derece şaşırtıcı veya iyi","e1":"The view from the mountain was amazing.","e1t":"Dağdan manzara harikaydı.","e2":"You look amazing today.","e2t":"Bugün harika görünüyorsun."},{"w":"ambition","tr":"hırs","te":"Noun","tt":"İsim","de":"A strong desire to achieve success","dt":"Başarıya ulaşmak için güçlü arzu","e1":"He has a lot of ambition.","e1t":"Çok hırsı var.","e2":"My ambition is to be a pilot.","e2t":"Hayalim (hırsım) pilot olmak."},{"w":"ambulance","tr":"ambulans","te":"Noun","tt":"İsim","de":"A vehicle that takes sick people to hospital","dt":"Hasta insanları hastaneye götüren araç","e1":"Call an ambulance!","e1t":"Bir ambulans çağırın!","e2":"The ambulance arrived quickly.","e2t":"Ambulans hızlıca vardı."},{"w":"amount","tr":"miktar","te":"Noun","tt":"İsim","de":"A quantity of something","dt":"Bir şeyin miktarı/niceliği","e1":"He spent a large amount of money.","e1t":"Büyük miktarda para harcadı.","e2":"What is the total amount?","e2t":"Toplam miktar nedir?"},{"w":"amusing","tr":"eğlenceli","te":"Adjective","tt":"Sıfat","de":"Funny or enjoyable","dt":"Komik veya keyifli","e1":"It was an amusing story.","e1t":"Eğlenceli bir hikayeydi.","e2":"He is a very amusing person.","e2t":"O çok eğlenceli biridir."},{"w":"analyse","tr":"analiz etmek","te":"Verb","tt":"Fiil","de":"To examine something in detail","dt":"Bir şeyi detaylıca incelemek","e1":"We need to analyse the data.","e1t":"Verileri analiz etmemiz gerekiyor.","e2":"Scientists analysed the soil.","e2t":"Bilim insanları toprağı analiz ettiler."},{"w":"analysis","tr":"analiz","te":"Noun","tt":"İsim","de":"A detailed examination of something","dt":"Bir şeyin detaylı incelemesi","e1":"The analysis showed interesting results.","e1t":"Analiz ilginç sonuçlar gösterdi.","e2":"He wrote a deep analysis of the book.","e2t":"Kitabın derin bir analizini yazdı."},{"w":"ancient","tr":"antik","te":"Adjective","tt":"Sıfat","de":"From a very long time ago","dt":"Çok uzun zaman öncesinden kalma","e1":"I love visiting ancient cities.","e1t":"Antik şehirleri ziyaret etmeyi severim.","e2":"Egypt is famous for ancient pyramids.","e2t":"Mısır antik piramitleriyle ünlüdür."},{"w":"angel","tr":"melek","te":"Noun","tt":"İsim","de":"A spiritual being in some religions","dt":"Bazı dinlerde ruhani varlık","e1":"She has the face of an angel.","e1t":"Bir melek yüzü var.","e2":"Thank you, you are an angel!","e2t":"Teşekkür ederim, sen bir meleksin!"},{"w":"angle","tr":"açı","te":"Noun","tt":"İsim","de":"The space between two joining lines","dt":"Birleşen iki çizgi arasındaki boşluk","e1":"Draw a 90","e1t":"degree angle.","e2":"90 derecelik bir açı çiz.","e2t":"Look at it from a different angle."},{"w":"ankle","tr":"ayak bileği","te":"Noun","tt":"İsim","de":"The joint between the foot and the leg","dt":"Ayak ile bacak arasındaki eklem","e1":"I twisted my ankle while running.","e1t":"Koşarken ayak bileğimi burktum.","e2":"Her ankle is swollen.","e2t":"Onun ayak bileği şişmiş."},{"w":"announce","tr":"duyurmak","te":"Verb","tt":"Fiil","de":"To make something known formally","dt":"Bir şeyi resmi olarak bilinir hale getirmek","e1":"The flight was announced.","e1t":"Uçuş duyuruldu.","e2":"They announced their wedding date.","e2t":"Düğün tarihlerini duyurdular."},{"w":"annoyed","tr":"sinirli","te":"Adjective","tt":"Sıfat","de":"Slightly angry or irritated","dt":"Hafifçe kızgın veya rahatsız olmuş","e1":"I am annoyed with his behavior.","e1t":"Onun davranışına sinir oldum.","e2":"She looked annoyed.","e2t":"Sinirli görünüyordu."},{"w":"annual","tr":"yıllık","te":"Adjective","tt":"Sıfat","de":"Happening once every year","dt":"Her yıl bir kez olan","e1":"We have an annual meeting in June.","e1t":"Haziran ayında yıllık bir toplantımız var.","e2":"What is your annual salary?","e2t":"Yıllık maaşın ne kadar?"},{"w":"ant","tr":"karınca","te":"Noun","tt":"İsim","de":"A small insect that lives in highly organized groups","dt":"Organize gruplar halinde yaşayan küçük böcek","e1":"Look at the ants on the wall.","e1t":"Duvardaki karıncalara bak.","e2":"Small ant.","e2t":"Küçük karınca."},{"w":"anticipate","tr":"beklemek","te":"Verb","tt":"Fiil","de":"To expect or predict something","dt":"Bir şeyi beklemek veya tahmin etmek","e1":"We anticipate a lot of visitors.","e1t":"Çok sayıda ziyaretçi bekliyoruz.","e2":"You should anticipate the problems.","e2t":"Sorunları önceden tahmin etmelisin."},{"w":"anxiety","tr":"kaygı","te":"Noun","tt":"İsim","de":"A feeling of worry or nervousness","dt":"Endişe veya gerginlik hissi","e1":"He suffers from anxiety.","e1t":"Kaygıdan (anksiyeteden) muzdarip.","e2":"There is a lot of anxiety about the future.","e2t":"Gelecek hakkında çok fazla kaygı var."},{"w":"anxious","tr":"endişeli","te":"Adjective","tt":"Sıfat","de":"Feeling worried or nervous","dt":"Endişeli veya gergin hissetme","e1":"I am anxious about the test.","e1t":"Test hakkında endişeliyim.","e2":"He looked anxious.","e2t":"Endişeli görünüyordu."},{"w":"anybody","tr":"herhangi biri","te":"Pronoun","tt":"Zamir","de":"Anyone; any person","dt":"Herhangi bir kişi","e1":"Is anybody home?","e1t":"Evde kimse var mı?","e2":"Anybody can join the club.","e2t":"Kulübe herhangi biri katılabilir."},{"w":"anymore","tr":"artık","te":"Adverb","tt":"Zarf","de":"Any longer (used in negative sentences)","dt":"Daha fazla (olumsuz cümlelerde kullanılır)","e1":"I don't live there anymore.","e1t":"Artık orada yaşamıyorum.","e2":"He doesn't smoke anymore.","e2t":"Artık sigara içmiyor."},{"w":"anyone","tr":"herhangi biri","te":"Pronoun","tt":"Zamir","de":"Any person","dt":"Herhangi bir kişi","e1":"I didn't see anyone.","e1t":"Kimseyi görmedim.","e2":"Anyone can learn English.","e2t":"Herkes (herhangi biri) İngilizce öğrenebilir."},{"w":"anything","tr":"herhangi bir şey","te":"Pronoun","tt":"Zamir","de":"A thing of any kind","dt":"Herhangi bir türden bir şey","e1":"Do you need anything?","e1t":"Bir şeye ihtiyacın var mı?","e2":"I don't know anything about it.","e2t":"Bu konuda hiçbir şey bilmiyorum."},{"w":"anyway","tr":"neyse","te":"Adverb","tt":"Zarf","de":"Used to change the subject","dt":"Konuyu değiştirmek için kullanılır","e1":"I'm busy, but thanks for calling anyway.","e1t":"Meşgulüm ama yine de (neyse) aradığın için teşekkürler.","e2":"Anyway, let's talk about something else.","e2t":"Neyse, başka bir şeyden konuşalım."},{"w":"anywhere","tr":"herhangi bir yer","te":"Adverb/Pronoun","tt":"Zarf/Zamir","de":"In or to any place","dt":"Herhangi bir yerde veya herhangi bir yere","e1":"I can't find my keys anywhere.","e1t":"Anahtarlarımı hiçbir yerde bulamıyorum.","e2":"Go anywhere.","e2t":"Herhangi bir yere gitmek."},{"w":"apart","tr":"ayrı","te":"Adverb","tt":"Zarf","de":"Separated by a distance or time","dt":"Mesafe veya zamanla ayrılmış","e1":"The two houses are 100 meters apart.","e1t":"İki ev birbirinden 100 metre uzakta.","e2":"My parents are living apart.","e2t":"Ebeveynlerim ayrı yaşıyorlar."},{"w":"apartment","tr":"apartman dairesi","te":"Noun","tt":"İsim","de":"A set of rooms for living in","dt":"Yaşamak için odalar seti","e1":"We live in a small apartment.","e1t":"Küçük bir dairede yaşıyoruz.","e2":"Is the apartment on the first floor?","e2t":"Daire birinci katta mı?"},{"w":"apologize","tr":"özür dilemek","te":"Verb","tt":"Fiil","de":"To say that you are sorry for something","dt":"Bir şey için üzgün olduğunu söylemek","e1":"You should apologize to her.","e1t":"Ondan özür dilemelisin.","e2":"I apologize for being late.","e2t":"Geç kaldığım için özür dilerim."},{"w":"app","tr":"uygulama","te":"Noun","tt":"İsim","de":"Short for application (software)","dt":"Uygulama kelimesinin kısaltması (yazılım)","e1":"Download the new app.","e1t":"Yeni uygulamayı indir.","e2":"This app is very useful.","e2t":"Bu uygulama çok kullanışlı."},{"w":"appeal","tr":"başvurmak / cezbetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a serious request or to be attractive","dt":"Ciddi bir talepte bulunmak veya çekici gelmek","e1":"The idea doesn't appeal to me.","e1t":"Bu fikir bana çekici gelmiyor.","e2":"He decided to appeal the decision.","e2t":"Karara itiraz etmeye (başvurmaya) karar verdi."},{"w":"appear","tr":"görünmek","te":"Verb","tt":"Fiil","de":"To become visible or seem to be","dt":"Görünür hale gelmek veya görünmek","e1":"A man appeared at the door.","e1t":"Kapıda bir adam belirdi.","e2":"He appears to be happy.","e2t":"Mutlu görünüyor."},{"w":"appearance","tr":"görünüş","te":"Noun","tt":"İsim","de":"The way that someone or something looks","dt":"Birinin veya bir şeyin nasıl göründüğü","e1":"Don't judge people by their appearance.","e1t":"İnsanları dış görünüşlerine göre yargılama.","e2":"She cares about her appearance.","e2t":"Dış görünüşüne önem verir."},{"w":"appetite","tr":"iştah","te":"Noun","tt":"İsim","de":"A natural desire to eat food","dt":"Yemek yemeye duyulan doğal arzu","e1":"I have a large appetite today.","e1t":"Bugün iştahım çok yerinde.","e2":"He lost his appetite.","e2t":"İştahı kapandı (kaybetti)."},{"w":"apply","tr":"başvurmak","te":"Verb","tt":"Fiil","de":"To make a formal request for something","dt":"Bir şey için resmi talepte bulunmak","e1":"I want to apply for this job.","e1t":"Bu işe başvurmak istiyorum.","e2":"You can apply online.","e2t":"İnternet üzerinden başvurabilirsiniz."},{"w":"appoint","tr":"atamak","te":"Verb","tt":"Fiil","de":"To choose someone for a job or position","dt":"Birini bir iş veya pozisyon için seçmek","e1":"They appointed him as the new manager.","e1t":"Onu yeni müdür olarak atadılar.","e2":"We need to appoint a date for the meeting.","e2t":"Toplantı için bir tarih belirlemeliyiz (atamalıyız)."},{"w":"approve","tr":"onaylamak","te":"Verb","tt":"Fiil","de":"To officially accept or think something is good","dt":"Resmi olarak kabul etmek veya iyi olduğunu düşünmek","e1":"My boss approved the project.","e1t":"Patronum projeyi onayladı.","e2":"Do you approve of my decision?","e2t":"Kararımı onaylıyor musun?"},{"w":"approximately","tr":"yaklaşık olarak","te":"Adverb","tt":"Zarf","de":"Used to show that something is almost correct","dt":"Bir şeyin neredeyse doğru olduğunu göstermek için kullanılır","e1":"The trip takes approximately two hours.","e1t":"Yolculuk yaklaşık iki saat sürer.","e2":"There were approximately 50 people.","e2t":"Yaklaşık 50 kişi vardı."},{"w":"apron","tr":"önlük (mutfak/iş)","te":"Noun","tt":"İsim","de":"A garment worn over the front of clothing to keep it clean","dt":"Giysiyi temiz tutmak için öne takılan koruyucu örtü","e1":"Put on your apron before cooking.","e1t":"Yemek pişirmeden önce önlüğünü tak.","e2":"Kitchen apron.","e2t":"Mutfak önlüğü."},{"w":"architect","tr":"mimar","te":"Noun","tt":"İsim","de":"A person who designs buildings","dt":"Binaları tasarlayan kişi","e1":"My father is an architect.","e1t":"Babam bir mimardır.","e2":"The architect designed a modern house.","e2t":"Mimar modern bir ev tasarladı."},{"w":"architecture","tr":"mimarlık","te":"Noun","tt":"İsim","de":"The design and style of buildings","dt":"Binaların tasarımı ve stili","e1":"He is studying architecture.","e1t":"Mimarlık okuyor.","e2":"I love the architecture of this city.","e2t":"Bu şehrin mimarisine bayılıyorum."},{"w":"area","tr":"alan","te":"Noun","tt":"İsim","de":"A particular part of a place or city","dt":"Bir yerin veya şehrin belirli bir bölümü","e1":"Is there a park in this area?","e1t":"Bu bölgede (alanda) bir park var mı?","e2":"This is a quiet residential area.","e2t":"Burası sessiz bir yerleşim alanıdır."},{"w":"argue","tr":"tartışmak","te":"Verb","tt":"Fiil","de":"To speak angrily with someone","dt":"Biriyle kızgın bir şekilde konuşmak","e1":"Don't argue with your parents.","e1t":"Ebeveynlerinle tartışma.","e2":"They argue about money all the time.","e2t":"Sürekli para hakkında tartışıyorlar."},{"w":"argument","tr":"tartışma","te":"Noun","tt":"İsim","de":"An angry disagreement","dt":"Kızgın bir anlaşmazlık","e1":"We had a big argument last night.","e1t":"Dün gece büyük bir tartışma yaşadık.","e2":"I don't want to start an argument.","e2t":"Bir tartışma başlatmak istemiyorum."},{"w":"arise","tr":"ortaya çıkmak","te":"Verb","tt":"Fiil","de":"To happen or begin to exist","dt":"Gerçekleşmek veya var olmaya başlamak","e1":"A new problem has arisen.","e1t":"Yeni bir sorun ortaya çıktı.","e2":"Questions often arise during the meeting.","e2t":"Toplantı sırasında sık sık sorular ortaya çıkar."},{"w":"armchair","tr":"koltuk (kollu)","te":"Noun","tt":"İsim","de":"A comfortable chair with sides that support your arms","dt":"Kollarınızı destekleyen kenarları olan rahat sandalye","e1":"My grandfather sits in his armchair.","e1t":"Büyükbabam koltuğunda oturur.","e2":"Old armchair.","e2t":"Eski koltuk."},{"w":"armed","tr":"silahlı","te":"Adjective","tt":"Sıfat","de":"Carrying weapons","dt":"Silah taşıyan","e1":"He is an armed guard.","e1t":"O silahlı bir korumadır.","e2":"The police are looking for an armed man.","e2t":"Polis silahlı bir adamı arıyor."},{"w":"armpit","tr":"koltuk altı","te":"Noun","tt":"İsim","de":"The hollow under the arm where it joins the shoulder","dt":"Kolun omuzla birleştiği yerdeki çukur kısım","e1":"He has a pain in his left armpit.","e1t":"Sol koltuk altında bir ağrı var.","e2":"Sweaty armpit.","e2t":"Terli koltuk altı."},{"w":"army","tr":"ordu","te":"Noun","tt":"İsim","de":"A large group of people trained to fight","dt":"Savaşmak için eğitilmiş büyük insan grubu","e1":"He joined the army last year.","e1t":"Geçen yıl orduya katıldı.","e2":"The army is protecting the border.","e2t":"Ordu sınırı koruyor."},{"w":"arrange","tr":"düzenlemek","te":"Verb","tt":"Fiil","de":"To plan or organize something","dt":"Bir şeyi planlamak veya organize etmek","e1":"I will arrange a meeting for tomorrow.","e1t":"Yarın için bir toplantı ayarlayacağım.","e2":"Can you arrange the flowers?","e2t":"Çiçekleri düzenleyebilir misin?"},{"w":"arrangement","tr":"düzenleme","te":"Noun","tt":"İsim","de":"A plan for how something will happen","dt":"Bir şeyin nasıl olacağına dair plan","e1":"We made an arrangement to meet at 5.","e1t":"Saat 5'te buluşmak için sözleştik (düzenleme yaptık).","e2":"What are the travel arrangements?","e2t":"Seyahat düzenlemeleri neler?"},{"w":"arrest","tr":"tutuklamak","te":"Verb","tt":"Fiil","de":"When the police take someone to prison","dt":"Polisin birini hapse/karakola götürmesi","e1":"The police arrested the thief.","e1t":"Polis hırsızı tutukladı.","e2":"He was arrested for stealing.","e2t":"Hırsızlıktan tutuklandı."},{"w":"arrival","tr":"varış","te":"Noun","tt":"İsim","de":"The act of reaching a place","dt":"Bir yere ulaşma eylemi","e1":"Check the arrival time of the flight.","e1t":"Uçuşun varış saatini kontrol et.","e2":"We are waiting for his arrival.","e2t":"Onun varışını bekliyoruz."},{"w":"arrive","tr":"varmak","te":"Verb","tt":"Fiil","de":"To reach a place","dt":"Bir yere ulaşmak","e1":"The train arrives at 10:00 AM.","e1t":"Tren sabah 10'da varıyor.","e2":"When did you arrive home?","e2t":"Eve ne zaman vardın?"},{"w":"arrow","tr":"ok (işaret)","te":"Noun","tt":"İsim","de":"A weapon or a sign pointing in a direction","dt":"Silah veya bir yönü gösteren işaret","e1":"Follow the arrows to the exit.","e1t":"Çıkış için okları takip et.","e2":"He shot an arrow at the target.","e2t":"Hedefe bir ok attı."},{"w":"article","tr":"makale","te":"Noun","tt":"İsim","de":"A piece of writing in a newspaper","dt":"Gazetedeki bir yazı parçası","e1":"I read an interesting article about AI.","e1t":"Yapay zeka hakkında ilginç bir makale okudum.","e2":"This article is very long.","e2t":"Bu makale çok uzun."},{"w":"artificial","tr":"yapay","te":"Adjective","tt":"Sıfat","de":"Made by humans, not natural","dt":"Doğal olmayan, insanlarca yapılmış","e1":"I don't like artificial flavors.","e1t":"Yapay aromaları sevmem.","e2":"Artificial intelligence is changing the world.","e2t":"Yapay zeka dünyayı değiştiriyor."},{"w":"artistic","tr":"sanatsal","te":"Adjective","tt":"Sıfat","de":"Relating to art or having creative skill","dt":"Sanatla ilgili veya yaratıcı beceriye sahip olma","e1":"She has great artistic talent.","e1t":"Büyük bir sanatsal yeteneği var.","e2":"This is an artistic photograph.","e2t":"Bu sanatsal bir fotoğraftır."},{"w":"ashamed","tr":"utanç duyan","te":"Adjective","tt":"Sıfat","de":"Feeling sorry or embarrassed for something wrong","dt":"Yanlış bir şey için üzgün veya utanmış hissetme","e1":"You should be ashamed of yourself.","e1t":"Kendinden utanmalısın.","e2":"He was too ashamed to speak.","e2t":"Konuşamayacak kadar utanmıştı."},{"w":"ashtray","tr":"küllük","te":"Noun","tt":"İsim","de":"A small dish for tobacco ash and cigarette ends","dt":"Sigara külü ve izmaritleri için küçük kap","e1":"Please empty the ashtray.","e1t":"Lütfen küllüğü boşaltın.","e2":"Glass ashtray.","e2t":"Cam küllük."},{"w":"aside","tr":"bir kenara","te":"Adverb","tt":"Zarf","de":"To one side; out of the way","dt":"Bir yana; yolun dışına","e1":"Move aside, please.","e1t":"Lütfen kenara çekilin.","e2":"Put your books aside.","e2t":"Kitaplarını bir kenara koy."},{"w":"asleep","tr":"uykuda","te":"Adjective","tt":"Sıfat","de":"Sleeping","dt":"Uyuyor olma durumu","e1":"The baby is fast asleep.","e1t":"Bebek derin uykuda.","e2":"He fell asleep during the movie.","e2t":"Film sırasında uyuyakaldı."},{"w":"assignment","tr":"görev","te":"Noun","tt":"İsim","de":"A piece of work given to someone","dt":"Birine verilen iş parçası","e1":"I have a lot of homework assignments.","e1t":"Çok fazla ödev görevim var.","e2":"When is the assignment due?","e2t":"Görevin (ödevin) son teslim tarihi ne zaman?"},{"w":"assist","tr":"yardım etmek","te":"Verb","tt":"Fiil","de":"To help someone to do something","dt":"Birine bir şey yapması için yardım etmek","e1":"Can you assist me with these bags?","e1t":"Bu çantalarda bana yardım edebilir misin?","e2":"He assisted the police.","e2t":"Polise yardım etti."},{"w":"assistant","tr":"asistan","te":"Noun","tt":"İsim","de":"A person who helps someone in a job","dt":"Birine işinde yardım eden kişi","e1":"She is a shop assistant.","e1t":"O bir mağaza satış elemanıdır.","e2":"I need a personal assistant.","e2t":"Kişisel bir asistana ihtiyacım var."},{"w":"associate","tr":"ilişkilendirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To connect someone or something in your mind","dt":"Zihninizde birini veya bir şeyi birleştirmek","e1":"I associate summer with the sea.","e1t":"Yazı denizle ilişkilendiririm.","e2":"He is a business associate.","e2t":"O bir iş ortağıdır (iş ortağı)."},{"w":"assume","tr":"varsaymak","te":"Verb","tt":"Fiil","de":"To think that something is true without proof","dt":"Kanıt olmadan bir şeyin doğru olduğunu düşünmek","e1":"Don't assume anything.","e1t":"Hiçbir şeyi varsayma.","e2":"I assumed you were at home.","e2t":"Senin evde olduğunu varsaydım (sanmıştım)."},{"w":"athlete","tr":"sporcu","te":"Noun","tt":"İsim","de":"A person who is good at sports","dt":"Spor dallarında iyi olan kişi","e1":"He is a professional athlete.","e1t":"O profesyonel bir sporcudur.","e2":"Many athletes use this gym.","e2t":"Birçok sporcu bu salonu kullanıyor."},{"w":"athletic","tr":"atletik","te":"Adjective","tt":"Sıfat","de":"Physically strong, fit, and active","dt":"Fiziksel olarak güçlü, formda ve aktif","e1":"She has an athletic body.","e1t":"Atletik bir vücudu var.","e2":"He is not very athletic.","e2t":"Çok atletik biri değildir."},{"w":"atmosphere","tr":"atmosfer","te":"Noun","tt":"İsim","de":"The air around the earth or the mood of a place","dt":"Dünyanın etrafındaki hava veya bir yerin havası","e1":"The restaurant has a great atmosphere.","e1t":"Restoranın harika bir atmosferi (havası) var.","e2":"Pollution is damaging the atmosphere.","e2t":"Kirlilik atmosfere zarar veriyor."},{"w":"attach","tr":"eklemek","te":"Verb","tt":"Fiil","de":"To fasten or join one thing to another","dt":"Bir şeyi diğerine sabitlemek veya birleştirmek","e1":"Please attach the file to the email.","e1t":"Lütfen dosyayı e","e2":"postaya ekleyin.","e2t":"He attached a label to the box."},{"w":"attack","tr":"saldırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To try to hurt someone with physical force","dt":"Birine fiziksel güçle zarar vermeye çalışmak","e1":"The dog attacked the mailman.","e1t":"Köpek postacıya saldırdı.","e2":"It was a sudden attack.","e2t":"Ani bir saldırıydı."},{"w":"attempt","tr":"girişimde bulunmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To try to do something difficult","dt":"Zor bir şeyi yapmaya çalışmak","e1":"He attempted to climb the mountain.","e1t":"Dağa tırmanmaya girişti (çalıştı).","e2":"It was a successful attempt.","e2t":"Başarılı bir girişimdi."},{"w":"attend","tr":"katılmak","te":"Verb","tt":"Fiil","de":"To go to an event or place","dt":"Bir etkinliğe veya yere gitmek","e1":"I will attend the meeting tomorrow.","e1t":"Yarın toplantıya katılacağım.","e2":"He attends university in Istanbul.","e2t":"İstanbul'da üniversiteye gidiyor (devam ediyor)."},{"w":"attention","tr":"dikkat","te":"Noun","tt":"İsim","de":"Notice taken of someone or something","dt":"Birine veya bir şeye verilen dikkat/ilgi","e1":"Please pay attention to the teacher.","e1t":"Lütfen öğretmene dikkat edin.","e2":"The project needs your full attention.","e2t":"Proje tüm dikkatinizi gerektiriyor."},{"w":"attic","tr":"tavan arası","te":"Noun","tt":"İsim","de":"A space or room inside the roof of a house","dt":"Evin çatısının altındaki boşluk veya oda","e1":"We store old boxes in the attic.","e1t":"Eski kutuları tavan arasında saklıyoruz.","e2":"Dusty attic.","e2t":"Tozlu tavan arası."},{"w":"attitude","tr":"tutum","te":"Noun","tt":"İsim","de":"A feeling or opinion about something","dt":"Bir şey hakkındaki duygu veya görüş","e1":"He has a positive attitude toward work.","e1t":"İşe karşı olumlu bir tutumu var.","e2":"Changing your attitude can change your life.","e2t":"Tutumunu değiştirmek hayatını değiştirebilir."},{"w":"attract","tr":"çekmek","te":"Verb","tt":"Fiil","de":"To pull towards or cause interest","dt":"Kendine çekmek veya ilgi uyandırmak","e1":"Magnets attract iron.","e1t":"Mıknatıslar demiri çeker.","e2":"The city attracts many tourists.","e2t":"Şehir birçok turisti çekiyor."},{"w":"attractive","tr":"çekici","te":"Adjective","tt":"Sıfat","de":"Pleasant to look at or interesting","dt":"Bakması hoş veya ilginç","e1":"She is a very attractive woman.","e1t":"O çok çekici bir kadındır.","e2":"I find the offer very attractive.","e2t":"Teklifi çok cazip (çekici) buluyorum."},{"w":"audience","tr":"izleyici","te":"Noun","tt":"İsim","de":"The people who watch or listen to a show","dt":"Bir gösteriyi izleyen veya dinleyen insanlar","e1":"The audience laughed at the joke.","e1t":"İzleyiciler şakaya güldü.","e2":"There was a large audience at the concert.","e2t":"Konserde büyük bir izleyici kitlesi vardı."},{"w":"aunt","tr":"teyze / hala","te":"Noun","tt":"İsim","de":"The sister of your father or mother","dt":"Anne veya babanın kız kardeşi","e1":"My aunt lives in Izmir.","e1t":"Teyzem (halam) İzmir'de yaşıyor.","e2":"Dear aunt.","e2t":"Sevgili teyze (hala)."},{"w":"author","tr":"yazar","te":"Noun","tt":"İsim","de":"A person who writes books or stories","dt":"Kitap veya hikaye yazan kişi","e1":"Who is the author of this book?","e1t":"Bu kitabın yazarı kim?","e2":"She is a famous author.","e2t":"O ünlü bir yazardır."},{"w":"authorities","tr":"yetkililer","te":"Noun","tt":"İsim","de":"People with official power","dt":"Resmi gücü olan insanlar","e1":"You should report it to the authorities.","e1t":"Bunu yetkililere bildirmelisin.","e2":"Local authorities are working on the project.","e2t":"Yerel yetkililer proje üzerinde çalışıyor."},{"w":"automatic","tr":"otomatik","te":"Adjective","tt":"Sıfat","de":"Working by itself without human control","dt":"İnsan kontrolü olmadan kendi kendine çalışma","e1":"This is an automatic car.","e1t":"Bu otomatik bir arabadır.","e2":"The door has an automatic lock.","e2t":"Kapının otomatik kilidi var."},{"w":"available","tr":"mevcut","te":"Adjective","tt":"Sıfat","de":"Able to be used or obtained","dt":"Kullanılabilir veya elde edilebilir","e1":"Is this room available?","e1t":"Bu oda müsait mi (boş mu)?","e2":"This dress is available in different colors.","e2t":"Bu elbise farklı renklerde mevcuttur."},{"w":"average","tr":"ortalama","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A standard or level that is normal","dt":"Normal olan bir standart veya seviye","e1":"The average temperature is 20 degrees.","e1t":"Ortalama sıcaklık 20 derecedir.","e2":"He is of average height.","e2t":"O ortalama boyda."},{"w":"avocado","tr":"avokado","te":"Noun","tt":"İsim","de":"A pear","dt":"shaped fruit with rough green skin and a large stone","e1":"Yeşil kabuklu, iri çekirdekli, armut biçimli meyve","e1t":"I like avocado on my toast.","e2":"Tostumun üzerinde avokadoyu severim.","e2t":"Ripe avocado."},{"w":"avoid","tr":"kaçınmak","te":"Verb","tt":"Fiil","de":"To stay away from something","dt":"Bir şeyden uzak durmak","e1":"You should avoid eating too much sugar.","e1t":"Çok fazla şeker yemekten kaçınmalısın.","e2":"I try to avoid traffic.","e2t":"Trafikten kaçınmaya çalışıyorum."},{"w":"awake","tr":"uyanık","te":"Adjective","tt":"Sıfat","de":"Not sleeping","dt":"Uyuyor olmama durumu","e1":"Are you awake?","e1t":"Uyanık mısın?","e2":"I was awake all night.","e2t":"Tüm gece uyanıktım."},{"w":"award","tr":"ödül","te":"Noun/Verb","tt":"İsim/Fiil","de":"A prize given for a success","dt":"Başarı için verilen ödül","e1":"He won an award for his book.","e1t":"Kitabı için bir ödül kazandı.","e2":"The committee awarded him the first prize.","e2t":"Komite ona birincilik ödülünü verdi."},{"w":"aware","tr":"farkında","te":"Adjective","tt":"Sıfat","de":"Knowing that something exists or is happening","dt":"Bir şeyin var olduğunu veya olduğunu bilme","e1":"Are you aware of the rules?","e1t":"Kuralların farkında mısın?","e2":"I wasn't aware of the problem.","e2t":"Sorunun farkında değildim."},{"w":"away","tr":"uzağa","te":"Adverb","tt":"Zarf","de":"To or at a distance from a place","dt":"Bir yerden uzağa veya uzak bir mesafede","e1":"Go away!","e1t":"Git buradan (uzaklaş)!","e2":"The station is 2 km away.","e2t":"İstasyon 2 km uzakta."},{"w":"backbone","tr":"omurga / temel taş","te":"Noun","tt":"İsim","de":"The series of vertebrae extending from the skull to the pelvis","dt":"Kafatasından leğen kemiğine kadar uzanan kemik dizisi","e1":"The spine is also called the backbone.","e1t":"Omurgaya \"backbone\" da denir.","e2":"The backbone of the team.","e2t":"Takımın temel taşı (omurgası)."},{"w":"background","tr":"arka plan","te":"Noun","tt":"İsim","de":"The part of a picture that is behind the main object","dt":"Resmin ana nesnesinin arkasındaki kısmı","e1":"The background of the photo is blue.","e1t":"Fotoğrafın arka planı mavi.","e2":"Tell me about your educational background.","e2t":"Eğitim geçmişin (arka planın) hakkında bana bilgi ver."},{"w":"backpack","tr":"sırt çantası","te":"Noun/Verb","tt":"İsim/Fiil","de":"A bag with shoulder straps that allow it to be carried on someone's back","dt":"Sırtta taşınan omuz askılı çanta","e1":"Put your books in your backpack.","e1t":"Kitaplarını sırt çantana koy.","e2":"Travel with a backpack.","e2t":"Sırt çantasıyla seyahat etmek."},{"w":"badly","tr":"kötü bir şekilde","te":"Adverb","tt":"Zarf","de":"In a severe or harmful way","dt":"Şiddetli veya zararlı bir şekilde","e1":"He was badly injured in the accident.","e1t":"Kazada kötü bir şekilde yaralandı.","e2":"The team played very badly.","e2t":"Takım çok kötü oynadı."},{"w":"baking powder","tr":"hamur kabartma tozu","te":"Noun","tt":"İsim","de":"A mixture used in baking to make cakes rise","dt":"Keklerin kabarması için kullanılan karışım","e1":"You need baking powder for this cake.","e1t":"Bu kek için kabartma tozuna ihtiyacın var.","e2":"A teaspoon of baking powder.","e2t":"Bir çay kaşığı kabartma tozu."},{"w":"balance","tr":"denge","te":"Noun/Verb","tt":"İsim/Fiil","de":"A state where things are equal or steady","dt":"Şeylerin eşit veya sabit olduğu durum","e1":"You need to keep your balance.","e1t":"Dengeni korumalısın.","e2":"He lost his balance and fell.","e2t":"Dengesi kaybetti ve düştü."},{"w":"bald","tr":"kel","te":"Adjective","tt":"Sıfat","de":"Having little or no hair on the head","dt":"Kafasında hiç veya çok az saç olan","e1":"He went bald in his twenties.","e1t":"Yirmili yaşlarında kel kaldı.","e2":"A bald head.","e2t":"Kel bir kafa."},{"w":"ballpoint","tr":"tükenmez kalem","te":"Noun","tt":"İsim","de":"A pen that has a small metal ball as its writing point","dt":"Yazma ucu küçük bir metal bilye olan kalem","e1":"I prefer writing with a ballpoint.","e1t":"Tükenmez kalemle yazmayı tercih ederim.","e2":"Blue ballpoint pen.","e2t":"Mavi tükenmez kalem."},{"w":"ban","tr":"yasaklamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To officially say that something is not allowed","dt":"Resmi olarak bir şeye izin verilmediğini söylemek","e1":"Smoking is banned in the building.","e1t":"Binada sigara içmek yasaktır.","e2":"There is a ban on plastic bags.","e2t":"Plastik torbalar üzerinde bir yasak var."},{"w":"band","tr":"grup (müzik)","te":"Noun","tt":"İsim","de":"A group of people who play music together","dt":"Birlikte müzik yapan bir grup insan","e1":"He plays guitar in a rock band.","e1t":"Bir rock grubunda gitar çalıyor.","e2":"My favorite band is on tour.","e2t":"En sevdiğim grup turda."},{"w":"barbecue","tr":"mangal / barbekü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A meal cooked outdoors on a rack over an open fire","dt":"Açık havada ızgara üzerinde pişirilen yemek","e1":"Let's have a barbecue on Sunday.","e1t":"Pazar günü mangal yapalım.","e2":"Barbecue sauce.","e2t":"Barbekü sosu."},{"w":"barcode","tr":"barkod","te":"Noun","tt":"İsim","de":"A machine","dt":"readable code in the form of parallel lines","e1":"Makine tarafından okunabilen paralel çizgili kod","e1t":"Scan the barcode to see the price.","e2":"Fiyatı görmek için barkodu taratın.","e2t":"Barcode reader."},{"w":"barely","tr":"zar zor","te":"Adverb","tt":"Zarf","de":"Only just; almost not","dt":"Sadece; neredeyse hiç","e1":"I could barely hear him.","e1t":"Onu zar zor duyabildim.","e2":"We have barely enough time.","e2t":"Neredeyse hiç (zar zor yetecek kadar) vaktimiz yok."},{"w":"barn","tr":"ahır / samanlık","te":"Noun","tt":"İsim","de":"A large farm building used for storing grain or housing livestock","dt":"Tahıl saklamak veya hayvan barındırmak için kullanılan büyük çiftlik binası","e1":"The horses are in the barn.","e1t":"Atlar ahırda.","e2":"Red barn.","e2t":"Kırmızı ahır."},{"w":"barrel","tr":"varil / namlu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A cylindrical container for liquids; or the tube of a gun","dt":"Sıvılar için silindirik kap; veya silah borusu","e1":"A barrel of oil.","e1t":"Bir varil petrol.","e2":"The barrel of the gun.","e2t":"Silahın namlusu."},{"w":"barrier","tr":"engel","te":"Noun","tt":"İsim","de":"Something that prevents movement or access","dt":"Hareketi veya erişimi engelleyen şey","e1":"Language is a barrier to communication.","e1t":"Dil, iletişim önünde bir engeldir.","e2":"There is a security barrier at the entrance.","e2t":"Girişte bir güvenlik bariyeri var."},{"w":"base","tr":"temel / üs","te":"Noun/Verb","tt":"İsim/Fiil","de":"The lowest part or the main place for work","dt":"En alt kısım veya ana çalışma yeri","e1":"The company's base is in London.","e1t":"Şirketin merkezi (üssü) Londra'dadır.","e2":"This movie is based on a true story.","e2t":"Bu film gerçek bir hikayeye dayanmaktadır (temellenmiştir)."},{"w":"basic","tr":"temel","te":"Adjective","tt":"Sıfat","de":"Simple or most important","dt":"Basit veya en önemli","e1":"I have a basic knowledge of English.","e1t":"Temel düzeyde İngilizce bilgim var.","e2":"Food and water are basic needs.","e2t":"Yiyecek ve su temel ihtiyaçlardır."},{"w":"basis","tr":"temel","te":"Noun","tt":"İsim","de":"The main idea or reason for something","dt":"Bir şeyin ana fikri veya sebebi","e1":"We meet on a regular basis.","e1t":"Düzenli bir temelde (düzenli olarak) buluşuyoruz.","e2":"What is the basis of your theory?","e2t":"Teorinizin temeli nedir?"},{"w":"bat","tr":"yarasa / sopa (beyzbol vb.)","te":"Noun","tt":"İsim","de":"A small animal like a mouse with wings; or a wooden stick for sports","dt":"Kanatlı fare benzeri hayvan; veya spor sopası","e1":"Bats fly at night.","e1t":"Yarasalar gece uçar.","e2":"Baseball bat.","e2t":"Beyzbol sopası."},{"w":"bathe","tr":"banyo yapmak / yıkamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To wash someone or something in a bath","dt":"Biri veya bir şeyi banyoda yıkamak","e1":"It's time to bathe the baby.","e1t":"Bebeği yıkama zamanı geldi.","e2":"Sunbathe.","e2t":"Güneşlenmek."},{"w":"batter","tr":"hamur karışımı (sıvı) / vurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A mixture of flour, eggs, and milk; or to hit hard","dt":"Un, yumurta ve süt karışımı; veya sertçe vurmak","e1":"Dip the fish in the batter.","e1t":"Balığı sulu hamura batır.","e2":"Pancake batter.","e2t":"Pankek hamuru."},{"w":"battery","tr":"pil / batarya","te":"Noun","tt":"İsim","de":"A device that stores electrical energy","dt":"Elektrik enerjisi depolayan cihaz","e1":"My phone's battery is low.","e1t":"Telefonumun şarjı (bataryası) az.","e2":"Rechargeable battery.","e2t":"Şarj edilebilir pil."},{"w":"battle","tr":"savaş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fight between large groups of people","dt":"Büyük insan grupları arasındaki çatışma","e1":"He died in a battle.","e1t":"Bir savaşta öldü.","e2":"They are battling against the disease.","e2t":"Hastalığa karşı savaşıyorlar."},{"w":"bay","tr":"koy / körfez","te":"Noun/Verb","tt":"İsim/Fiil","de":"A broad inlet of the sea where the land curves inward","dt":"Karaya doğru kıvrılan geniş deniz girişi","e1":"The boat is in the bay.","e1t":"Tekne koyda.","e2":"A beautiful bay.","e2t":"Güzel bir koy."},{"w":"bead","tr":"boncuk","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of glass or stone used for jewelry","dt":"Takı için kullanılan küçük cam veya taş parça","e1":"She is making a necklace with glass beads.","e1t":"Cam boncuklarla bir kolye yapıyor.","e2":"Blue beads.","e2t":"Mavi boncuklar."},{"w":"beak","tr":"gaga","te":"Noun","tt":"İsim","de":"The hard pointed mouth of a bird","dt":"Kuşun sert ve sivri ağzı","e1":"The bird has a yellow beak.","e1t":"Kuşun sarı bir gagası var.","e2":"Sharp beak.","e2t":"Keskin gaga."},{"w":"bean","tr":"fasulye","te":"Noun","tt":"İsim","de":"A seed or pod of a plant eaten as food","dt":"Yiyecek olarak yenen bitki tohumu veya kapsülü","e1":"I like green beans.","e1t":"Taze fasulyeyi severim.","e2":"Coffee beans are roasted.","e2t":"Kahve çekirdekleri (fasulyeleri) kavrulur."},{"w":"bear","tr":"ayı / katlanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large heavy animal or to accept something","dt":"Büyük ağır bir hayvan veya bir şeye katlanmak","e1":"I saw a bear in the forest.","e1t":"Ormanda bir ayı gördüm.","e2":"I can't bear this noise.","e2t":"Bu gürültüye katlanamıyorum."},{"w":"beard","tr":"sakal","te":"Noun","tt":"İsim","de":"The hair growing on the chin and lower cheeks of a man's face","dt":"Bir erkeğin çenesinde ve yanaklarının alt kısmında çıkan kıllar","e1":"He decided to grow a beard.","e1t":"Sakal bırakmaya karar verdi.","e2":"Long beard.","e2t":"Uzun sakal."},{"w":"beast","tr":"canavar / hayvan","te":"Noun","tt":"İsim","de":"A large or wild animal","dt":"Büyük veya vahşi hayvan","e1":"He is a beast in the field.","e1t":"Sahada bir canavar gibi.","e2":"The story is about Beauty and the Beast.","e2t":"Hikaye Güzel ve Çirkin (Canavar) hakkındadır."},{"w":"beat","tr":"yenmek / vurmak","te":"Verb","tt":"Fiil","de":"To defeat someone in a game","dt":"Birini bir oyunda mağlup etmek","e1":"Our team beat them 3","e1t":"0.","e2":"Takımımız onları 3","e2t":"0 yendi."},{"w":"beauty","tr":"güzellik","te":"Noun","tt":"İsim","de":"The quality of being pleasing to look at","dt":"Bakması hoş olma özelliği","e1":"The sunset was a thing of beauty.","e1t":"Gün batımı bir güzellik abidesiydi.","e2":"She is famous for her beauty.","e2t":"Güzelliğiyle ünlüdür."},{"w":"bedsheet","tr":"çarşaf","te":"Noun","tt":"İsim","de":"A large piece of cloth used to cover a mattress","dt":"Yatağı kaplamak için kullanılan büyük kumaş","e1":"Put clean bedsheets on the bed.","e1t":"Yatağa temiz çarşaflar ser.","e2":"Cotton bedsheet.","e2t":"Pamuklu çarşaf."},{"w":"bee","tr":"arı","te":"Noun","tt":"İsim","de":"A black and yellow insect that makes honey","dt":"Bal yapan siyah ve sarı böcek","e1":"A bee stung me on the arm.","e1t":"Kolumdan bir arı soktu.","e2":"Bees are important for the environment.","e2t":"Arılar çevre için önemlidir."},{"w":"beef","tr":"sığır eti","te":"Noun","tt":"İsim","de":"Meat from a cow","dt":"İnek eti","e1":"Do you prefer beef or chicken?","e1t":"Sığır etini mi yoksa tavuğu mu tercih edersin?","e2":"I'll have a beef burger.","e2t":"Bir dana (sığır) burger alacağım."},{"w":"beehive","tr":"arı kovanı","te":"Noun","tt":"İsim","de":"A structure in which bees are kept","dt":"Arıların tutulduğu yapı","e1":"Don't go near the beehive.","e1t":"Arı kovanının yakınına gitme.","e2":"Bees in a beehive.","e2t":"Kovandaki arılar."},{"w":"beetroot","tr":"pancar","te":"Noun","tt":"İsim","de":"The edible dark red root of a plant","dt":"Bitkinin yenilebilir koyu kırmızı kökü","e1":"I like beetroot salad.","e1t":"Pancar salatasını severim.","e2":"Red beetroot.","e2t":"Kırmızı pancar."},{"w":"beg","tr":"yalvarmak","te":"Verb","tt":"Fiil","de":"To ask for something very strongly or for money","dt":"Bir şeyi çok güçlü bir şekilde veya para istemek","e1":"He begged for forgiveness.","e1t":"Affedilmek için yalvardı.","e2":"There were people begging in the street.","e2t":"Sokakta dilenen (yalvaran) insanlar vardı."},{"w":"beginner","tr":"yeni başlayan / acemi","te":"Noun","tt":"İsim","de":"A person just starting to learn a skill or take part in an activity","dt":"Bir beceriyi öğrenmeye veya bir faaliyete katılmaya yeni başlayan kişi","e1":"This class is for beginners.","e1t":"Bu sınıf yeni başlayanlar içindir.","e2":"Total beginner.","e2t":"Tam bir acemi."},{"w":"behave","tr":"davranmak","te":"Verb","tt":"Fiil","de":"To act in a particular way","dt":"Belirli bir şekilde hareket etmek/davranmak","e1":"Please behave yourself.","e1t":"Lütfen uslu dur (düzgün davran).","e2":"The children behaved very well today.","e2t":"Çocuklar bugün çok iyi davrandılar."},{"w":"behavior","tr":"davranış","te":"Noun","tt":"İsim","de":"The way that someone acts","dt":"Birinin hareket etme biçimi","e1":"His behavior at school is very good.","e1t":"Okuldaki davranışı çok iyi.","e2":"I don't understand her behavior.","e2t":"Onun davranışını anlamıyorum."},{"w":"belief","tr":"inanç","te":"Noun","tt":"İsim","de":"A feeling that something is true or exists","dt":"Bir şeyin doğru veya var olduğuna dair duygu","e1":"It is a common belief that luck is important.","e1t":"Şansın önemli olduğu yaygın bir inançtır.","e2":"He has strong religious beliefs.","e2t":"Onun güçlü dini inançları var."},{"w":"bell pepper","tr":"dolmalık biber","te":"Noun","tt":"İsim","de":"A large, mild","dt":"flavored vegetable","e1":"Büyük, hafif aromalı sebze","e1t":"Put red bell peppers in the salad.","e2":"Salataya kırmızı dolmalık biber koy.","e2t":"Green bell pepper."},{"w":"bellows","tr":"körük","te":"Noun","tt":"İsim","de":"A device used for blowing air into a fire","dt":"Ateşe hava üflemek için kullanılan araç","e1":"Use the bellows to start the fire.","e1t":"Ateşi başlatmak için körüğü kullan.","e2":"(Plural: bellows).","e2t":""},{"w":"belong","tr":"ait olmak","te":"Verb","tt":"Fiil","de":"To be the property of someone","dt":"Birinin mülkü olmak","e1":"Does this bag belong to you?","e1t":"Bu çanta sana mı ait?","e2":"This book belongs on the shelf.","e2t":"Bu kitap rafa ait (orada durmalı)."},{"w":"bend","tr":"bükmek / eğilmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something so it is not straight","dt":"Bir şeyi düz olmayacak şekilde hareket ettirmek","e1":"Bend your knees.","e1t":"Dizlerini bük.","e2":"There is a sharp bend in the road.","e2t":"Yolda keskin bir viraj (büküm) var."},{"w":"beneath","tr":"altında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Under or at a lower level","dt":"Altında veya daha düşük bir seviyede","e1":"The keys were beneath the cushion.","e1t":"Anahtarlar minderin altındaydı.","e2":"He felt it was beneath him.","e2t":"Bunun kendisinden aşağıda (ona yakışmaz) olduğunu hissetti."},{"w":"benefit","tr":"fayda","te":"Noun/Verb","tt":"İsim/Fiil","de":"An advantage or profit gained from something","dt":"Bir şeyden elde edilen avantaj veya kar","e1":"Exercise has many health benefits.","e1t":"Egzersizin birçok sağlık faydası vardır.","e2":"Who will benefit from this project?","e2t":"Bu projeden kim faydalanacak?"},{"w":"bent","tr":"bükülmüş","te":"Adjective","tt":"Sıfat","de":"Not straight","dt":"Düz olmayan","e1":"The nail is bent.","e1t":"Çivi bükülmüş.","e2":"He has a bent back.","e2t":"Kambur (bükük) bir sırtı var."},{"w":"beret","tr":"bere (ressam beresi)","te":"Noun","tt":"İsim","de":"A round flattish cap of felt or soft wool","dt":"Keçeden veya yumuşak yünden yapılan yuvarlak, yassı şapka","e1":"She wears a red beret.","e1t":"O kırmızı bir bere takıyor.","e2":"French beret.","e2t":"Fransız beresi."},{"w":"berry","tr":"dutsu meyve (çilek, böğürtlen vb.)","te":"Noun","tt":"İsim","de":"A small pulpy and edible fruit","dt":"Küçük etli ve yenilebilir meyve","e1":"Go to the forest to pick berries.","e1t":"Ormana meyve (berry) toplamaya git.","e2":"Wild berries.","e2t":"Yabani meyveler."},{"w":"besides","tr":"ayrıca / dışında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"In addition to or apart from","dt":"Ek olarak veya dışında","e1":"Besides English, I can speak German.","e1t":"İngilizcenin yanı sıra (dışında) Almanca da konuşabiliyorum.","e2":"There was no one there besides me.","e2t":"Orada benden başka (dışında) kimse yoktu."},{"w":"best","tr":"selling","te":"en çok satan","tt":"Adjective","de":"Sıfat","dt":"Selling in very large numbers","e1":"Çok büyük sayılarda satılan","e1t":"This is a best","e2":"selling novel.","e2t":"Bu en çok satan bir romandır."},{"w":"beyond","tr":"ötesinde","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Further away in the distance","dt":"Mesafede daha uzakta","e1":"The village is beyond those mountains.","e1t":"Köy şu dağların ötesinde.","e2":"This problem is beyond my control.","e2t":"Bu sorun benim kontrolümün ötesinde."},{"w":"billion","tr":"milyar","te":"Number","tt":"Sayı","de":"The number 1,000,000,000","dt":"1.000.000.000 sayısı","e1":"The world population is over 8 billion.","e1t":"Dünya nüfusu 8 milyarın üzerinde.","e2":"He is a billionaire.","e2t":"O bir milyarderdir."},{"w":"bin","tr":"çöp kutusu","te":"Noun","tt":"İsim","de":"A container for waste","dt":"Atıklar için bir kap","e1":"Put the empty bottle in the bin.","e1t":"Boş şişeyi çöp kutusuna at.","e2":"Where is the kitchen bin?","e2t":"Mutfak çöpü nerede?"},{"w":"binocular(s)","tr":"dürbün","te":"Noun","tt":"İsim","de":"An optical instrument for seeing distant objects","dt":"Uzaktaki nesneleri görmek için optik araç","e1":"Use your binoculars to see the birds.","e1t":"Kuşları görmek için dürbününü kullan.","e2":"A pair of binoculars.","e2t":"Bir dürbün."},{"w":"biography","tr":"biyografi","te":"Noun","tt":"İsim","de":"The story of a person's life","dt":"Bir kişinin hayatının hikayesi","e1":"I am reading a biography of Atatürk.","e1t":"Atatürk'ün biyografisini okuyorum.","e2":"He wrote his father's biography.","e2t":"Babasının biyografisini yazdı."},{"w":"biologist","tr":"biyolog","te":"Noun","tt":"İsim","de":"An expert in or student of the branch of science that deals with living organisms","dt":"Canlı organizmalarla ilgilenen bilim dalı uzmanı","e1":"My sister wants to be a biologist.","e1t":"Kız kardeşim biyolog olmak istiyor.","e2":"Marine biologist.","e2t":"Deniz biyoloğu."},{"w":"biology","tr":"biyoloji","te":"Noun","tt":"İsim","de":"The scientific study of living things","dt":"Canlıların bilimsel incelemesi","e1":"Biology was my favorite subject.","e1t":"Biyoloji en sevdiğim dersti.","e2":"He is a biology teacher.","e2t":"O bir biyoloji öğretmenidir."},{"w":"birth","tr":"doğum","te":"Noun","tt":"İsim","de":"The time when a baby is born","dt":"Bir bebeğin doğduğu an","e1":"What is your date of birth?","e1t":"Doğum tarihiniz nedir?","e2":"She gave birth to a healthy baby.","e2t":"Sağlıklı bir bebek dünyaya getirdi."},{"w":"bit","tr":"biraz / parça","te":"Noun/Adverb","tt":"A small piece or amount","de":"Küçük bir parça veya miktar","dt":"Wait a bit.","e1":"Biraz bekle.","e1t":"Can you move a bit?","e2":"Biraz kıpırdayabilir misin?","e2t":""},{"w":"bite","tr":"ısırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To use teeth to cut something","dt":"Bir şeyi kesmek için dişleri kullanmak","e1":"Does your dog bite?","e1t":"Köpeğin ısırır mı?","e2":"Take a bite of this apple.","e2t":"Bu elmadan bir ısırık al."},{"w":"blackboard","tr":"kara tahta","te":"Noun","tt":"İsim","de":"A large board with a smooth dark surface for writing on with chalk","dt":"Tebeşirle üzerine yazılan geniş koyu yüzeyli tahta","e1":"Clean the blackboard, please.","e1t":"Kara tahtayı temizle lütfen.","e2":"Write on the blackboard.","e2t":"Tahtaya yazmak."},{"w":"blade","tr":"bıçak ağzı / kanat","te":"Noun","tt":"İsim","de":"The sharp part of a tool or a thin leaf","dt":"Bir aletin keskin kısmı veya ince yaprak","e1":"The razor blade is very sharp.","e1t":"Jilet bıçağı çok keskindir.","e2":"The blades of the helicopter are spinning.","e2t":"Helikopterin pervaneleri (kanatları) dönüyor."},{"w":"blame","tr":"suçlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say or think that someone did something wrong","dt":"Birinin yanlış bir şey yaptığını söylemek veya düşünmek","e1":"Don't blame me for your mistakes.","e1t":"Hataların için beni suçlama.","e2":"Who is to blame?","e2t":"Suçlu kim?"},{"w":"blank","tr":"boşluk / boş","te":"Adjective/Noun/Verb","tt":"Not written or printed on; empty","de":"Üzerinde yazı olmayan; boş","dt":"Fill in the blanks.","e1":"Boşlukları doldurun.","e1t":"A blank sheet of paper.","e2":"Boş bir kağıt sayfası.","e2t":""},{"w":"blanket","tr":"battaniye","te":"Noun","tt":"İsim","de":"A warm cover for a bed","dt":"Yatak için sıcak örtü","e1":"I need an extra blanket.","e1t":"Ekstra bir battaniyeye ihtiyacım var.","e2":"Wrap the baby in a blanket.","e2t":"Bebeği bir battaniyeye sar."},{"w":"bleach","tr":"çamaşır suyu / ağartmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A chemical used to make things white or clean","dt":"Eşyaları beyazlatmak veya temizlemek için kullanılan kimyasal","e1":"Use bleach for the white clothes.","e1t":"Beyaz kıyafetler için çamaşır suyu kullan.","e2":"Bleach your hair.","e2t":"Saçını açmak (ağartmak)."},{"w":"blind","tr":"kör","te":"Adjective/Noun/Verb","tt":"Unable to see","de":"Görememe durumu","dt":"He is blind in one eye.","e1":"Bir gözü kör.","e1t":"The sun is blinding me.","e2":"Güneş gözlerimi kamaştırıyor (kör ediyor).","e2t":""},{"w":"blizzard","tr":"tipi / kar fırtınası","te":"Noun","tt":"İsim","de":"A severe snowstorm with high winds","dt":"Şiddetli rüzgarlı kar fırtınası","e1":"We couldn't go out because of the blizzard.","e1t":"Tipi nedeniyle dışarı çıkamadık.","e2":"Winter blizzard.","e2t":"Kış fırtınası."},{"w":"block","tr":"blok / engellemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large piece of hard material or to stop movement","dt":"Sert bir malzeme parçası veya hareketi durdurmak","e1":"He lives in a large apartment block.","e1t":"Büyük bir apartman bloğunda yaşıyor.","e2":"Don't block the road.","e2t":"Yolu kapatma (engelleme)."},{"w":"blood","tr":"kan","te":"Noun","tt":"İsim","de":"The red liquid that flows through the body","dt":"Vücutta akan kırmızı sıvı","e1":"The doctor took a blood sample.","e1t":"Doktor kan örneği aldı.","e2":"He lost a lot of blood.","e2t":"Çok kan kaybetti."},{"w":"blossom","tr":"çiçek (meyve ağacı) / çiçek açmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flower or a mass of flowers on a tree","dt":"Ağaç üzerindeki çiçek veya çiçek topluluğu","e1":"Cherry blossoms are beautiful.","e1t":"Kiraz çiçekleri güzeldir.","e2":"Trees blossom in spring.","e2t":"Ağaçlar baharda çiçek açar."},{"w":"blow","tr":"üflemek / esmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move air with force","dt":"Havayı kuvvetle hareket ettirmek","e1":"Blow out the candles.","e1t":"Mumları üfle.","e2":"The wind is blowing hard.","e2t":"Rüzgar sert esiyor."},{"w":"bluebottle","tr":"et sineği","te":"Noun","tt":"İsim","de":"A large blowfly with a metallic blue body","dt":"Metalik mavi gövdeli büyük sinek","e1":"There is a bluebottle in the kitchen.","e1t":"Mutfakta bir et sineği var.","e2":"(Bkz: Fly).","e2t":""},{"w":"blunt","tr":"kör (keskin olmayan) / kaba (açık sözlü)","te":"Adjective/Verb","tt":"Not sharp; or very direct in speech","de":"Keskin olmayan; veya konuşmada çok direkt/kaba","dt":"This knife is blunt.","e1":"Bu bıçak kör (kesmiyor).","e1t":"A blunt answer.","e2":"Kaba / direkt bir cevap.","e2t":""},{"w":"blush","tr":"kızarmak (utanmak)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become red in the face because of embarrassment","dt":"Utançtan dolayı yüzün kırmızı olması","e1":"She blushed when he looked at her.","e1t":"Ona baktığında yüzü kızardı.","e2":"Make someone blush.","e2t":"Birini utandırmak (kızartmak)."},{"w":"boar","tr":"yaban domuzu","te":"Noun","tt":"İsim","de":"A wild pig","dt":"Yabani domuz","e1":"Wild boars live in the forest.","e1t":"Yaban domuzları ormanda yaşar.","e2":"(Bkz: Pig).","e2t":""},{"w":"board","tr":"tahta / binmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat piece of wood or to get on a plane/ship","dt":"Düz bir tahta parçası veya uçağa/gemiye binmek","e1":"Write it on the board.","e1t":"Onu tahtaya yaz.","e2":"Passengers are boarding the plane.","e2t":"Yolcular uçağa biniyor."},{"w":"bobbin","tr":"masura / makara","te":"Noun","tt":"İsim","de":"A cylinder or cone on which thread is wound","dt":"İpliğin sarıldığı silindir veya koni","e1":"Put the bobbin in the sewing machine.","e1t":"Masurayı dikiş makinesine koy.","e2":"Thread bobbin.","e2t":"İplik makarası."},{"w":"boil","tr":"kaynatmak","te":"Verb","tt":"Fiil","de":"To heat a liquid until it turns to gas","dt":"Bir sıvıyı gaz haline gelene kadar ısıtmak","e1":"Boil some water for the tea.","e1t":"Çay için biraz su kaynat.","e2":"The water is boiling.","e2t":"Su kaynıyor."},{"w":"bolt","tr":"sürgü / cıvata / fırlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A metal bar for fastening a door; or a type of screw","dt":"Kapıyı sabitlemek için metal çubuk; veya bir vida türü","e1":"Slide the bolt to lock the door.","e1t":"Kapıyı kilitlemek için sürgüyü çek.","e2":"Nuts and bolts.","e2t":"Somunlar ve cıvatalar."},{"w":"bomb","tr":"bomba","te":"Noun/Verb","tt":"İsim/Fiil","de":"A weapon that explodes","dt":"Patlayan silah","e1":"The bomb exploded at midnight.","e1t":"Bomba gece yarısı patladı.","e2":"The movie was a total bomb (failure).","e2t":"Film tam bir fiyaskoydu (bomba)."},{"w":"bond","tr":"bağ","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong connection between people","dt":"İnsanlar arasındaki güçlü bağlantı","e1":"There is a close bond between the brothers.","e1t":"Kardeşler arasında yakın bir bağ var.","e2":"Water molecules bond together.","e2t":"Su molekülleri birbirine bağlanır."},{"w":"bone","tr":"kemik","te":"Noun","tt":"İsim","de":"The hard parts inside a human or animal body","dt":"İnsan veya hayvan vücudunun içindeki sert kısımlar","e1":"He broke a bone in his leg.","e1t":"Bacağındaki bir kemiği kırdı.","e2":"Dogs like chewing bones.","e2t":"Köpekler kemik çiğnemeyi sever."},{"w":"bonfire","tr":"büyük ateş / şenlik ateşi","te":"Noun","tt":"İsim","de":"A large open","dt":"air fire used as part of a celebration","e1":"Kutlamanın parçası olarak yakılan büyük açık hava ateşi","e1t":"They built a bonfire on the beach.","e2":"Sahilde büyük bir ateş yaktılar.","e2t":"Sit around the bonfire."},{"w":"bookcase","tr":"kitaplık","te":"Noun","tt":"İsim","de":"A piece of furniture with shelves for books","dt":"Kitaplar için rafları olan mobilya","e1":"Put the novels on the bookcase.","e1t":"Romanları kitaplığa koy.","e2":"(Bkz: Shelf).","e2t":""},{"w":"bookmark","tr":"kitap ayracı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strip of leather or card used to mark a place in a book","dt":"Kitapta kalınan yeri işaretlemek için kullanılan deri veya kart","e1":"I need a bookmark for my storybook.","e1t":"Hikaye kitabım için bir ayraca ihtiyacım var.","e2":"Digital bookmark.","e2t":"Dijital yer imi."},{"w":"bookstore","tr":"kitapçı (mağaza)","te":"Noun","tt":"İsim","de":"A shop where books are sold","dt":"Kitap satılan dükkan","e1":"I am going to the bookstore to buy a pen.","e1t":"Kalem almak için kitapçıya gidiyorum.","e2":"(Bkz: Bookshop).","e2t":""},{"w":"boot","tr":"bot / çizme / bagaj (İngiltere)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sturdy item of footwear covering the foot and ankle; or a car's luggage space","dt":"Ayağı ve bileği kapatan sağlam ayakkabı; veya araba bagajı","e1":"Put the bags in the boot of the car.","e1t":"Çantaları arabanın bagajına koy.","e2":"Leather boots.","e2t":"Deri botlar."},{"w":"border","tr":"sınır","te":"Noun/Verb","tt":"İsim/Fiil","de":"The line that separates two countries","dt":"İki ülkeyi ayıran çizgi","e1":"We crossed the border between Turkey and Greece.","e1t":"Türkiye ve Yunanistan arasındaki sınırı geçtik.","e2":"The garden has a flower border.","e2t":"Bahçenin çiçek kenarlığı (sınırı) var."},{"w":"bore","tr":"sıkmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make someone feel tired and uninterested","dt":"Birinin yorgun ve ilgisiz hissetmesini sağlamak","e1":"This lecture is boring me.","e1t":"Bu ders beni sıkıyor.","e2":"He is a total bore.","e2t":"O tam bir sıkıcı tip."},{"w":"bored","tr":"sıkılmış","te":"Adjective","tt":"Sıfat","de":"Feeling tired and impatient","dt":"Yorgun ve sabırsız hissetme","e1":"I'm bored, let's go out.","e1t":"Sıkıldım, hadi dışarı çıkalım.","e2":"He looked bored during the meeting.","e2t":"Toplantı sırasında sıkılmış görünüyordu."},{"w":"boring","tr":"sıkıcı","te":"Adjective","tt":"Sıfat","de":"Not interesting","dt":"İlginç olmayan","e1":"This book is very boring.","e1t":"Bu kitap çok sıkıcı.","e2":"I have a boring job.","e2t":"Sıkıcı bir işim var."},{"w":"born","tr":"doğmuş","te":"Verb","tt":"Fiil","de":"To be brought into life","dt":"Hayata getirilmiş olmak","e1":"I was born in 1980.","e1t":"1980'de doğdum.","e2":"Where were you born?","e2t":"Nerede doğdun?"},{"w":"borrow","tr":"ödünç almak","te":"Verb","tt":"Fiil","de":"To take something and return it later","dt":"Bir şeyi alıp sonra geri vermek","e1":"Can I borrow your umbrella?","e1t":"Şemsiyeni ödünç alabilir miyim?","e2":"I borrowed this book from the library.","e2t":"Bu kitabı kütüphaneden ödünç aldım."},{"w":"bother","tr":"rahatsız etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To annoy or worry someone","dt":"Birini kızdırmak veya endişelendirmek","e1":"Don't bother me while I'm working.","e1t":"Çalışırken beni rahatsız etme.","e2":"It's no bother at all.","e2t":"Hiç zahmet (rahatsızlık) değil."},{"w":"bottom","tr":"alt","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The lowest part of something","dt":"Bir şeyin en alt kısmı","e1":"The keys are at the bottom of the bag.","e1t":"Anahtarlar çantanın en altındadır.","e2":"He sat on the bottom step.","e2t":"En alt basamağa oturdu."},{"w":"bowl","tr":"kase","te":"Noun","tt":"İsim","de":"A round deep dish for food","dt":"Yemek için yuvarlak derin kap","e1":"I ate a bowl of soup.","e1t":"Bir kase çorbayı yedim.","e2":"Put the fruit in the bowl.","e2t":"Meyveleri kaseye koy."},{"w":"box","tr":"kutu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A container for objects or a sport","dt":"Nesneler için kap veya bir spor dalı","e1":"Put the toys in the box.","e1t":"Oyuncakları kutuya koy.","e2":"He likes to box.","e2t":"Boks yapmayı sever."},{"w":"boxer","tr":"boksör","te":"Noun","tt":"İsim","de":"A person who takes part in boxing","dt":"Boks yapan kişi","e1":"He is a famous heavyweight boxer.","e1t":"O ünlü bir ağır sıklet boksörüdür.","e2":"(Bkz: Boxing).","e2t":""},{"w":"bracelet","tr":"bilezik / bileklik","te":"Noun","tt":"İsim","de":"An ornamental band worn on the wrist or arm","dt":"Bileğe veya kola takılan süs eşyası","e1":"She bought a gold bracelet.","e1t":"Altın bir bilezik satın aldı.","e2":"Friendship bracelet.","e2t":"Arkadaşlık bilekliği."},{"w":"bracket","tr":"parantez / destek (raf)","te":"Noun/Verb","tt":"İsim/Fiil","de":"Punctuation marks ( ); or a support for a shelf","dt":"( ) işaretleri; veya raf desteği","e1":"Put the word in brackets.","e1t":"Kelimeyi parantez içine al.","e2":"Shelf bracket.","e2t":"Raf desteği."},{"w":"brake","tr":"fren / fren yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device for slowing or stopping a moving vehicle","dt":"Hareketli aracı yavaşlatma veya durdurma aracı","e1":"Hit the brakes!","e1t":"Frene bas!","e2":"Brake suddenly.","e2t":"Aniden fren yapmak."},{"w":"branch","tr":"dal / şube","te":"Noun","tt":"İsim","de":"A part of a tree or a local office","dt":"Bir ağacın parçası veya yerel ofis","e1":"The bird sat on a branch.","e1t":"Kuş bir dalın üzerine kondu.","e2":"The bank has a branch in our town.","e2t":"Bankanın kasabamızda bir şubesi var."},{"w":"brand","tr":"marka","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of product made by a company","dt":"Bir şirket tarafından yapılan ürün türü","e1":"What is your favorite brand of shoes?","e1t":"En sevdiğin ayakkabı markası hangisi?","e2":"They are branding the new product.","e2t":"Yeni ürünü markalaştırıyorlar."},{"w":"brave","tr":"cesur","te":"Adjective","tt":"Sıfat","de":"Showing no fear in dangerous situations","dt":"Tehlikeli durumlarda korku göstermeyen","e1":"He is a very brave soldier.","e1t":"O çok cesur bir askerdir.","e2":"It was a brave decision.","e2t":"Cesurca bir karardı."},{"w":"breast","tr":"göğüs","te":"Noun","tt":"İsim","de":"Either of the two soft organs on a woman's chest","dt":"Bir kadının göğsündeki iki yumuşak organdan her biri","e1":"The baby is sleeping on its mother's breast.","e1t":"Bebek annesinin göğsünde uyuyor.","e2":"Chicken breast is lean meat.","e2t":"Tavuk göğsü yağsız ettir."},{"w":"breath","tr":"nefes","te":"Noun","tt":"İsim","de":"The air that you take into your lungs","dt":"Akciğerlerinize aldığınız hava","e1":"Take a deep breath.","e1t":"Derin bir nefes al.","e2":"His breath smells like coffee.","e2t":"Nefesi kahve gibi kokuyor."},{"w":"breathe","tr":"nefes almak","te":"Verb","tt":"Fiil","de":"To take air into and out of the lungs","dt":"Akciğerlere hava alıp vermek","e1":"Breathe in deeply.","e1t":"Derince nefes al.","e2":"It is difficult to breathe here.","e2t":"Burada nefes almak zor."},{"w":"breathing","tr":"solunum","te":"Noun","tt":"İsim","de":"The process of taking air into the lungs","dt":"Akciğerlere hava alma süreci","e1":"His breathing was slow and steady.","e1t":"Solunumu yavaş ve düzenliydi.","e2":"Yoga focuses on deep breathing.","e2t":"Yoga derin solunuma odaklanır."},{"w":"brick","tr":"tuğla","te":"Noun","tt":"İsim","de":"A rectangular block used for building walls","dt":"Duvar örmek için kullanılan dikdörtgen blok","e1":"The house is made of red bricks.","e1t":"Ev kırmızı tuğlalardan yapılmıştır.","e2":"He threw a brick through the window.","e2t":"Pencereden içeri bir tuğla attı."},{"w":"brief","tr":"kısa","te":"Adjective","tt":"Sıfat","de":"Lasting only a short time","dt":"Sadece kısa bir süre süren","e1":"He gave a brief explanation.","e1t":"Kısa bir açıklama yaptı.","e2":"We had a brief meeting.","e2t":"Kısa bir toplantı yaptık."},{"w":"briefly","tr":"kısaca","te":"Adverb","tt":"Zarf","de":"For a short time or in a few words","dt":"Kısa bir süre için veya birkaç kelimeyle","e1":"Please explain it briefly.","e1t":"Lütfen kısaca açıklayın.","e2":"He spoke briefly about the project.","e2t":"Proje hakkında kısaca konuştu."},{"w":"bright","tr":"parlak","te":"Adjective","tt":"Sıfat","de":"Giving out much light or intelligent","dt":"Çok ışık veren veya zeki","e1":"The sun is very bright today.","e1t":"Bugün güneş çok parlak.","e2":"She is a bright student.","e2t":"O zeki (parlak) bir öğrencidir."},{"w":"brilliant","tr":"parlak / zeki","te":"Adjective","tt":"Sıfat","de":"Extremely clever or bright","dt":"Son derece zeki veya parlak","e1":"That is a brilliant idea!","e1t":"Bu harika (dahice) bir fikir!","e2":"She is a brilliant student.","e2t":"O çok zeki bir öğrenci."},{"w":"broad","tr":"geniş","te":"Adjective","tt":"Sıfat","de":"Very wide or including many things","dt":"Çok geniş veya birçok şeyi içeren","e1":"He has broad shoulders.","e1t":"Geniş omuzları var.","e2":"The report covers a broad range of topics.","e2t":"Rapor geniş bir konu yelpazesini kapsıyor."},{"w":"broadcast","tr":"yayın yapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To send out a program on TV or radio","dt":"TV veya radyoda bir program yayınlamak","e1":"The match was broadcast live.","e1t":"Maç canlı yayınlandı.","e2":"This is a daily news broadcast.","e2t":"Bu günlük bir haber yayınıdır."},{"w":"broken","tr":"kırık","te":"Adjective","tt":"Sıfat","de":"Damaged or in pieces","dt":"Hasar görmüş veya parçalara ayrılmış","e1":"The window is broken.","e1t":"Pencere kırık.","e2":"My phone is broken, I need a new one.","e2t":"Telefonum bozuk/kırık, yenisine ihtiyacım var."},{"w":"bronze","tr":"bronz","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A yellowish","dt":"brown metal made of copper and tin","e1":"Bakır ve kalaydan yapılan sarımsı kahverengi metal","e1t":"He won a bronze medal.","e2":"Bronz madalya kazandı.","e2t":"The statue is made of bronze."},{"w":"brush","tr":"fırçalamak / fırça","te":"Verb/Noun","tt":"Fiil/İsim","de":"To clean with a brush or the tool itself","dt":"Fırça ile temizlemek veya aletin kendisi","e1":"Brush your teeth after meals.","e1t":"Yemeklerden sonra dişlerini fırçala.","e2":"I need a new hairbrush.","e2t":"Yeni bir saç fırçasına ihtiyacım var."},{"w":"bucket","tr":"kova","te":"Noun","tt":"İsim","de":"An open container with a handle for water","dt":"Su için saplı açık kap","e1":"Fill the bucket with water.","e1t":"Kovayı suyla doldur.","e2":"We used a bucket to clean the floor.","e2t":"Yeri temizlemek için bir kova kullandık."},{"w":"budget","tr":"bütçe","te":"Noun/Verb","tt":"İsim/Fiil","de":"A plan of how to spend money","dt":"Paranın nasıl harcanacağına dair plan","e1":"We are on a tight budget.","e1t":"Kısıtlı bir bütçemiz var.","e2":"You need to budget your expenses.","e2t":"Masraflarını bütçelendirmen (planlaman) gerekiyor."},{"w":"build","tr":"inşa etmek","te":"Verb","tt":"Fiil","de":"To make something by putting parts together","dt":"Parçaları birleştirerek bir şey yapmak","e1":"They are building a new bridge.","e1t":"Yeni bir köprü inşa ediyorlar.","e2":"He built his own house.","e2t":"Kendi evini inşa etti."},{"w":"builder","tr":"inşaatçı","te":"Noun","tt":"İsim","de":"A person whose job is to build houses","dt":"İşi ev inşa etmek olan kişi","e1":"The builder finished the roof.","e1t":"İnşaatçı çatıyı bitirdi.","e2":"We hired a builder to renovate the kitchen.","e2t":"Mutfağı yenilemek için bir inşaatçı tuttuk."},{"w":"building","tr":"bina","te":"Noun","tt":"İsim","de":"A structure with walls and a roof","dt":"Duvarları ve çatısı olan yapı","e1":"This is the tallest building in the city.","e1t":"Bu şehirdeki en yüksek binadır.","e2":"The building is made of glass and steel.","e2t":"Bina cam ve çelikten yapılmıştır."},{"w":"bullet","tr":"mermi","te":"Noun","tt":"İsim","de":"A small metal object fired from a gun","dt":"Silahla atılan küçük metal nesne","e1":"The bullet hit the wall.","e1t":"Mermi duvara çarptı.","e2":"He was killed by a single bullet.","e2t":"Tek bir mermiyle öldürüldü."},{"w":"bunch","tr":"demet / salkım","te":"Noun","tt":"İsim","de":"A number of things growing or held together","dt":"Bir arada büyüyen veya tutulan bir dizi şey","e1":"I bought a bunch of bananas.","e1t":"Bir salkım muz aldım.","e2":"He gave her a bunch of flowers.","e2t":"Ona bir demet çiçek verdi."},{"w":"burden","tr":"yük","te":"Noun/Verb","tt":"İsim/Fiil","de":"A heavy load or a difficult responsibility","dt":"Ağır yük veya zor bir sorumluluk","e1":"I don't want to be a burden to you.","e1t":"Sana yük olmak istemiyorum.","e2":"Tax is a heavy burden for poor people.","e2t":"Vergi fakir insanlar için ağır bir yüktür."},{"w":"burn","tr":"yanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be on fire or damaged by heat","dt":"Ateş almak veya ısıdan zarar görmek","e1":"Be careful, don't burn yourself.","e1t":"Dikkatli ol, kendini yakma.","e2":"The wood burns slowly.","e2t":"Odun yavaş yanıyor."},{"w":"burst","tr":"patlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break open suddenly","dt":"Aniden kırılıp açılmak","e1":"The balloon burst.","e1t":"Balon patladı.","e2":"He burst into the room.","e2t":"Odaya daldı (aniden girdi)."},{"w":"bury","tr":"gömmek","te":"Verb","tt":"Fiil","de":"To put a dead body or object in the ground","dt":"Ölü bir vücudu veya nesneyi yere koymak","e1":"They buried the treasure in the garden.","e1t":"Hazineyi bahçeye gömdüler.","e2":"The dog buried its bone.","e2t":"Köpek kemiğini gömdü."},{"w":"bus station","tr":"otobüs terminali","te":"Noun","tt":"İsim","de":"A place where many buses start and end trips","dt":"Birçok otobüsün seferine başladığı ve bitirdiği yer","e1":"Where is the nearest bus station?","e1t":"En yakın otobüs terminali nerede?","e2":"I'll meet you at the bus station.","e2t":"Seninle otobüs terminalinde buluşacağız."},{"w":"bush","tr":"çalı","te":"Noun","tt":"İsim","de":"A plant that is smaller than a tree","dt":"Ağaçtan küçük bitki","e1":"There is a bird in the bush.","e1t":"Çalının içinde bir kuş var.","e2":"He is hiding behind the bush.","e2t":"Çalının arkasına saklanıyor."},{"w":"business","tr":"iş","te":"Noun","tt":"İsim","de":"The activity of buying and selling goods","dt":"Mal alım satım faaliyeti","e1":"He has a successful business.","e1t":"Başarılı bir işi var.","e2":"None of your business!","e2t":"Seni ilgilendirmez (senin işin değil)!"},{"w":"businessman","tr":"iş adamı","te":"Noun","tt":"İsim","de":"A man who works in business","dt":"İş dünyasında çalışan adam","e1":"He is a successful businessman.","e1t":"O başarılı bir iş adamıdır.","e2":"The businessman has a meeting today.","e2t":"İş adamının bugün bir toplantısı var."},{"w":"busy","tr":"meşgul","te":"Adjective","tt":"Sıfat","de":"Having a lot of things to do","dt":"Yapacak çok şeyi olma","e1":"I am very busy today.","e1t":"Bugün çok meşgulüm.","e2":"The street is busy with traffic.","e2t":"Sokak trafikle dolu (meşgul)."},{"w":"butter","tr":"tereyağı","te":"Noun","tt":"İsim","de":"A yellow fat made from milk","dt":"Sütten yapılan sarı yağ","e1":"Put some butter on the bread.","e1t":"Ekmeğin üzerine biraz tereyağı sür.","e2":"I prefer butter to margarine.","e2t":"Tereyağını margarine tercih ederim."},{"w":"butterfly","tr":"kelebek","te":"Noun","tt":"İsim","de":"An insect with large colorful wings","dt":"Büyük renkli kanatları olan böcek","e1":"A beautiful butterfly landed on the flower.","e1t":"Çiçeğin üzerine güzel bir kelebek kondu.","e2":"The butterfly's life is very short.","e2t":"Kelebeğin ömrü çok kısadır."},{"w":"button","tr":"düğme / buton","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small round object on clothes or a switch","dt":"Giysilerdeki küçük yuvarlak nesne veya bir anahtar","e1":"Your shirt is missing a button.","e1t":"Gömleğinin bir düğmesi eksik.","e2":"Press the button to start the machine.","e2t":"Makineyi başlatmak için butona bas."},{"w":"buyer","tr":"alıcı","te":"Noun","tt":"İsim","de":"A person who buys something","dt":"Bir şey satın alan kişi","e1":"We found a buyer for the house.","e1t":"Ev için bir alıcı bulduk.","e2":"The buyer requested a discount.","e2t":"Alıcı bir indirim talep etti."},{"w":"by","tr":"tarafından / yanında","te":"Preposition","tt":"Edat","de":"Near to or through the action of","dt":"Yanında veya ... eylemi aracılığıyla","e1":"The book was written by Orhan Pamuk.","e1t":"Kitap Orhan Pamuk tarafından yazıldı.","e2":"Sit by me.","e2t":"Yanıma otur."},{"w":"cabin","tr":"kabin / kulübe","te":"Noun","tt":"İsim","de":"A small wooden house or a room on a ship","dt":"Küçük ahşap ev veya gemideki oda","e1":"We stayed in a log cabin in the mountains.","e1t":"Dağlarda bir kütük kulübede kaldık.","e2":"The pilot is in the cabin.","e2t":"Pilot kabinde."},{"w":"cabinet","tr":"kabine / dolap","te":"Noun","tt":"İsim","de":"A cupboard or a group of government ministers","dt":"Dolap veya hükümet bakanları grubu","e1":"Put the dishes in the kitchen cabinet.","e1t":"Tabakları mutfak dolabına koy.","e2":"The Prime Minister is meeting the cabinet.","e2t":"Başbakan kabineyle görüşüyor."},{"w":"cable","tr":"kablo","te":"Noun","tt":"İsim","de":"A thick wire or a bundle of wires","dt":"Kalın tel veya tel demeti","e1":"I need a longer cable for my computer.","e1t":"Bilgisayarım için daha uzun bir kabloya ihtiyacım var.","e2":"They are laying undersea cables.","e2t":"Deniz altı kabloları döşüyorlar."},{"w":"cake","tr":"kek / pasta","te":"Noun","tt":"İsim","de":"A sweet food made from flour, eggs, and sugar","dt":"Un, yumurta ve şekerden yapılan tatlı yiyecek","e1":"I baked a chocolate cake.","e1t":"Çikolatalı bir kek pişirdim.","e2":"Would you like a piece of cake?","e2t":"Bir parça kek ister misin?"},{"w":"calculate","tr":"hesaplamak","te":"Verb","tt":"Fiil","de":"To find an answer using numbers","dt":"Sayıları kullanarak bir cevap bulmak","e1":"Can you calculate the total cost?","e1t":"Toplam maliyeti hesaplayabilir misin?","e2":"Scientists calculated the distance to the moon.","e2t":"Bilim insanları aya olan mesafeyi hesapladılar."},{"w":"calculation","tr":"hesaplama","te":"Noun","tt":"İsim","de":"The process of using numbers to find an answer","dt":"Bir cevap bulmak için sayıları kullanma süreci","e1":"My calculations show that we need more money.","e1t":"Hesaplamalarım daha fazla paraya ihtiyacımız olduğunu gösteriyor.","e2":"The calculation was correct.","e2t":"Hesaplama doğruydu."},{"w":"calculator","tr":"hesap makinesi","te":"Noun","tt":"İsim","de":"A small electronic device for math","dt":"Matematik için küçük elektronik cihaz","e1":"Can I use your calculator?","e1t":"Hesap makineni kullanabilir miyim?","e2":"I forgot my calculator in the classroom.","e2t":"Hesap makinemi sınıfta unuttum."},{"w":"calendar","tr":"takvim","te":"Noun","tt":"İsim","de":"A system or chart showing days and months","dt":"Günleri ve ayları gösteren sistem veya çizelge","e1":"Check the date on the calendar.","e1t":"Takvimdeki tarihi kontrol et.","e2":"I have a busy calendar this month.","e2t":"Bu ay yoğun bir takvimim var."},{"w":"calm","tr":"sakin","te":"Adjective/Verb","tt":"Peaceful, quiet, or not excited","de":"Huzurlu, sessiz veya heyecanlı olmayan","dt":"The sea is very calm today.","e1":"Bugün deniz çok sakin.","e1t":"Try to stay calm.","e2":"Sakin kalmaya çalış.","e2t":""},{"w":"camel","tr":"deve","te":"Noun","tt":"İsim","de":"A large animal with humps that lives in deserts","dt":"Çöllerde yaşayan, hörgüçlü büyük hayvan","e1":"Camels can travel for days without water.","e1t":"Develer susuz günlerce seyahat edebilir.","e2":"We saw camels in the desert.","e2t":"Çölde develer gördük."},{"w":"camp","tr":"kamp / kamp yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where people stay in tents","dt":"İnsanların çadırlarda kaldığı yer","e1":"We set up camp near the lake.","e1t":"Gölün yanına kamp kurduk.","e2":"I love to camp in the forest.","e2t":"Ormanda kamp yapmayı severim."},{"w":"campaign","tr":"kampanya","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of planned activities to achieve a goal","dt":"Bir hedefe ulaşmak için planlanmış faaliyetler serisi","e1":"The election campaign starts next week.","e1t":"Seçim kampanyası haftaya başlıyor.","e2":"They are campaigning for human rights.","e2t":"İnsan hakları için kampanya yürütüyorlar."},{"w":"camping","tr":"kamp yapma","te":"Noun","tt":"İsim","de":"The activity of staying in a tent","dt":"Çadırda kalma faaliyeti","e1":"We are going camping this weekend.","e1t":"Bu hafta sonu kampa gidiyoruz.","e2":"Camping is a great way to relax.","e2t":"Kamp yapmak rahatlamak için harika bir yoldur."},{"w":"campus","tr":"kampüs","te":"Noun","tt":"İsim","de":"The grounds and buildings of a university","dt":"Bir üniversitenin arazisi ve binaları","e1":"The university campus is very green.","e1t":"Üniversite kampüsü çok yeşil.","e2":"He lives on campus.","e2t":"Kampüste yaşıyor."},{"w":"can","tr":"yapabilmek / kutu","te":"Modal/Noun","tt":"To be able to or a metal container","de":"Yapabilmek (yetenek) veya metal kutu (teneke)","dt":"Can you swim?","e1":"Yüzebilir misin?","e1t":"I bought a can of soda.","e2":"Bir kutu soda aldım.","e2t":""},{"w":"canal","tr":"kanal","te":"Noun","tt":"İsim","de":"An artificial river for water or boats","dt":"Su veya tekneler için yapay nehir","e1":"The Panama Canal is very famous.","e1t":"Panama Kanalı çok ünlüdür.","e2":"They are traveling through the canal.","e2t":"Kanal boyunca seyahat ediyorlar."},{"w":"cancel","tr":"iptal etmek","te":"Verb","tt":"Fiil","de":"To decide that a planned event will not happen","dt":"Planlanmış bir etkinliğin olmayacağına karar vermek","e1":"They had to cancel the flight.","e1t":"Uçuşu iptal etmek zorunda kaldılar.","e2":"Can I cancel my reservation?","e2t":"Rezervasyonumu iptal edebilir miyim?"},{"w":"cancer","tr":"kanser","te":"Noun","tt":"İsim","de":"A serious disease caused by abnormal cells","dt":"Anormal hücrelerin neden olduğu ciddi bir hastalık","e1":"Smoking causes lung cancer.","e1t":"Sigara içmek akciğer kanserine neden olur.","e2":"Scientists are looking for a cure for cancer.","e2t":"Bilim insanları kanser için bir tedavi arıyorlar."},{"w":"candidate","tr":"aday","te":"Noun","tt":"İsim","de":"A person who is competing for a job or position","dt":"Bir iş veya pozisyon için yarışan kişi","e1":"There are three candidates for the job.","e1t":"İş için üç aday var.","e2":"He is a strong candidate.","e2t":"O güçlü bir aday."},{"w":"candle","tr":"mum","te":"Noun","tt":"İsim","de":"A stick of wax that gives light when burned","dt":"Yakıldığında ışık veren balmumu çubuğu","e1":"Light the candles on the cake.","e1t":"Kekin üzerindeki mumları yak.","e2":"We had a candlelit dinner.","e2t":"Mum ışığında bir akşam yemeği yedik."},{"w":"candy","tr":"şekerleme","te":"Noun","tt":"İsim","de":"Sweet food made with sugar (American English)","dt":"Şekerle yapılan tatlı yiyecek (Amerikan İngilizcesi)","e1":"Children love candy.","e1t":"Çocuklar şekeri sever.","e2":"Don't eat too much candy.","e2t":"Çok fazla şeker yeme."},{"w":"cap","tr":"şapka / kapak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of soft hat or a lid","dt":"Yumuşak şapka (kep) veya kapak","e1":"He is wearing a baseball cap.","e1t":"Beyzbol şapkası takıyor.","e2":"Put the cap back on the bottle.","e2t":"Şişenin kapağını geri tak."},{"w":"capable","tr":"yetenekli / yapabilir","te":"Adjective","tt":"Sıfat","de":"Able to do something well","dt":"Bir şeyi iyi yapabilen","e1":"She is a very capable manager.","e1t":"Çok yetenekli (becerikli) bir müdürdür.","e2":"I am capable of doing it myself.","e2t":"Onu kendim yapabilirim."},{"w":"capacity","tr":"kapasite","te":"Noun","tt":"İsim","de":"The maximum amount that something can contain","dt":"Bir şeyin içerebileceği maksimum miktar","e1":"The stadium has a capacity of 50,000.","e1t":"Stadyumun 50.000 kişilik kapasitesi var.","e2":"He has a great capacity for learning.","e2t":"Onun büyük bir öğrenme kapasitesi var."},{"w":"capital","tr":"başkent","te":"Noun","tt":"İsim","de":"The most important city of a country","dt":"Bir ülkenin en önemli şehri","e1":"Ankara is the capital of Turkey.","e1t":"Ankara Türkiye'nin başkentidir.","e2":"Paris is the capital city of France.","e2t":"Paris Fransa'nın başkentidir."},{"w":"captain","tr":"kaptan","te":"Noun","tt":"İsim","de":"The person in charge of a ship or team","dt":"Bir geminin veya takımın sorumlusu","e1":"The captain of the ship is experienced.","e1t":"Geminin kaptanı deneyimlidir.","e2":"He is the captain of the football team.","e2t":"Futbol takımının kaptanıdır."},{"w":"capture","tr":"yakalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To catch someone or record an image","dt":"Birini yakalamak veya bir görüntüyü kaydetmek","e1":"The police captured the thief.","e1t":"Polis hırsızı yakaladı.","e2":"This photo captures the beauty of the city.","e2t":"Bu fotoğraf şehrin güzelliğini yansıtıyor (yakalıyor)."},{"w":"carbon","tr":"karbon","te":"Noun","tt":"İsim","de":"A chemical element found in all living things","dt":"Tüm canlılarda bulunan kimyasal bir element","e1":"Carbon dioxide is a greenhouse gas.","e1t":"Karbondioksit bir sera gazıdır.","e2":"Diamonds are made of carbon.","e2t":"Elmaslar karbondan oluşur."},{"w":"card","tr":"kart","te":"Noun","tt":"İsim","de":"A piece of stiff paper or a credit card","dt":"Sert kağıt parçası veya kredi kartı","e1":"Can I pay by card?","e1t":"Kartla ödeyebilir miyim?","e2":"Send me a birthday card.","e2t":"Bana bir doğum günü kartı gönder."},{"w":"career","tr":"kariyer","te":"Noun","tt":"İsim","de":"A job or profession followed for a long time","dt":"Uzun süre takip edilen iş veya meslek","e1":"She wants a career in medicine.","e1t":"Tıp alanında bir kariyer istiyor.","e2":"He changed his career at 40.","e2t":"40 yaşında kariyerini değiştirdi."},{"w":"careful","tr":"dikkatli","te":"Adjective","tt":"Sıfat","de":"Giving a lot of attention to what you are doing","dt":"Yaptığınız şeye çok dikkat etmek","e1":"Be careful with the glasses!","e1t":"Bardaklara dikkat et!","e2":"She is a very careful driver.","e2t":"O çok dikkatli bir sürücüdür."},{"w":"carefully","tr":"dikkatlice","te":"Adverb","tt":"Zarf","de":"In a careful way","dt":"Dikkatli bir şekilde","e1":"Read the instructions carefully.","e1t":"Talimatları dikkatlice oku.","e2":"Please handle the box carefully.","e2t":"Lütfen kutuyu dikkatlice taşıyın."},{"w":"careless","tr":"dikkatsiz","te":"Adjective","tt":"Sıfat","de":"Not giving enough attention to what you are doing","dt":"Yaptığınız şeye yeterince dikkat etmemek","e1":"It was a careless mistake.","e1t":"Dikkatsizce yapılmış bir hataydı.","e2":"Don't be so careless.","e2t":"Bu kadar dikkatsiz olma."},{"w":"cargo","tr":"kargo / yük","te":"Noun","tt":"İsim","de":"Goods carried by a ship, plane, or truck","dt":"Gemi, uçak veya kamyonla taşınan mallar","e1":"The ship is carrying a cargo of oil.","e1t":"Gemi petrol yükü (kargosu) taşıyor.","e2":"The cargo plane landed at midnight.","e2t":"Kargo uçağı gece yarısı indi."},{"w":"carpet","tr":"halı","te":"Noun","tt":"İsim","de":"Thick material used for covering floors","dt":"Zeminleri kaplamak için kullanılan kalın malzeme","e1":"The carpet in the room is red.","e1t":"Odadaki halı kırmızı.","e2":"We need to clean the carpet.","e2t":"Halıyı temizlememiz gerekiyor."},{"w":"carry","tr":"taşımak","te":"Verb","tt":"Fiil","de":"To hold and move something to another place","dt":"Bir şeyi tutup başka bir yere götürmek","e1":"Can you help me carry these bags?","e1t":"Bu çantaları taşımama yardım edebilir misin?","e2":"He always carries a notebook with him.","e2t":"Yanında her zaman bir defter taşır."},{"w":"cart","tr":"el arabası / sepet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle with wheels used for carrying things","dt":"Bir şeyleri taşımak için kullanılan tekerlekli araç","e1":"Put the groceries in the shopping cart.","e1t":"Market alışverişini alışveriş sepetine (arabasına) koy.","e2":"The horse is pulling a wooden cart.","e2t":"At ahşap bir arabayı çekiyor."},{"w":"cartoon","tr":"çizgi film","te":"Noun","tt":"İsim","de":"A film made using animation","dt":"Animasyon kullanılarak yapılan film","e1":"Children love watching cartoons.","e1t":"Çocuklar çizgi film izlemeyi sever.","e2":"This is my favorite cartoon character.","e2t":"Bu benim en sevdiğim çizgi film karakteri."},{"w":"case","tr":"vaka / durum / dava","te":"Noun","tt":"İsim","de":"A particular situation or a legal matter","dt":"Belirli bir durum veya yasal mesele","e1":"In that case, I will stay at home.","e1t":"Bu durumda, evde kalacağım.","e2":"The police are investigating the case.","e2t":"Polis vakayı (davayı) araştırıyor."},{"w":"cashier","tr":"kasiyer","te":"Noun","tt":"İsim","de":"A person who handles money in a shop","dt":"Dükkanda parayı yöneten kişi","e1":"Give the money to the cashier.","e1t":"Parayı kasiyere ver.","e2":"The cashier gave me the wrong change.","e2t":"Kasiyer bana yanlış para üstü verdi."},{"w":"castle","tr":"kale","te":"Noun","tt":"İsim","de":"A large building with high walls for protection","dt":"Korunma amaçlı yüksek duvarlı büyük bina","e1":"We visited an old castle in Scotland.","e1t":"İskoçya'da eski bir kaleyi ziyaret ettik.","e2":"The king lived in a castle.","e2t":"Kral bir kalede yaşıyordu."},{"w":"casual","tr":"gündelik / rahat","te":"Adjective","tt":"Sıfat","de":"Relaxed and informal","dt":"Rahat ve resmi olmayan","e1":"He wore casual clothes to the party.","e1t":"Partiye gündelik kıyafetler giydi.","e2":"It was a casual conversation.","e2t":"Sıradan (rahat) bir konuşmaydı."},{"w":"catalog","tr":"katalog","te":"Noun/Verb","tt":"İsim/Fiil","de":"A list of items that you can buy or see","dt":"Satın alabileceğiniz veya görebileceğiniz ürünler listesi","e1":"Look at the product catalog.","e1t":"Ürün kataloğuna bak.","e2":"They are cataloging the new books.","e2t":"Yeni kitapları katalogluyorlar (listeliyorlar)."},{"w":"catch","tr":"yakalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop and hold something that is moving","dt":"Hareket eden bir şeyi durdurup tutmak","e1":"Catch the ball!","e1t":"Topu yakala!","e2":"I need to catch the 8 o'clock train.","e2t":"Saat 8 trenine yetişmem (yakalamam) gerekiyor."},{"w":"category","tr":"kategori","te":"Noun","tt":"İsim","de":"A group of people or things with similar features","dt":"Benzer özelliklere sahip insan veya eşya grubu","e1":"The books are divided into categories.","e1t":"Kitaplar kategorilere ayrılmıştır.","e2":"Which category does this belong to?","e2t":"Bu hangisine (hangi kategoriye) ait?"},{"w":"cattle","tr":"sığır / davar","te":"Noun","tt":"İsim","de":"Cows and bulls kept for milk or meat","dt":"Süt veya et için beslenen inek ve boğalar","e1":"The farmer has a lot of cattle.","e1t":"Çiftçinin birçok sığırı var.","e2":"Cattle are grazing in the field.","e2t":"Sığırlar alanda otluyorlar."},{"w":"cauliflower","tr":"karnabahar","te":"Noun","tt":"İsim","de":"A large round white vegetable","dt":"Büyük yuvarlak beyaz sebze","e1":"I like fried cauliflower.","e1t":"Karnabahar kızartmasını severim.","e2":"Fresh cauliflower.","e2t":"Taze karnabahar."},{"w":"cause","tr":"sebep olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something happen","dt":"Bir şeyin olmasını sağlamak","e1":"Smoking can cause cancer.","e1t":"Sigara içmek kansere sebep olabilir.","e2":"What was the cause of the accident?","e2t":"Kazanın sebebi neydi?"},{"w":"caution","tr":"dikkat / tedbir","te":"Noun/Verb","tt":"İsim/Fiil","de":"Care taken to avoid danger or a warning","dt":"Tehlikeden kaçınmak için gösterilen özen veya uyarı","e1":"You should proceed with caution.","e1t":"Dikkatle (tedbirle) ilerlemelisin.","e2":"The police cautioned him about his behavior.","e2t":"Polis onu davranışı konusunda uyardı."},{"w":"cave","tr":"mağara","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large hole in the side of a hill or under the ground","dt":"Bir tepenin yan tarafında veya yer altında bulunan büyük delik","e1":"They found ancient paintings in the cave.","e1t":"Mağarada antik tablolar buldular.","e2":"The roof of the tunnel caved in.","e2t":"Tünelin çatısı çöktü (içe doğru çöktü)."},{"w":"ceiling","tr":"tavan","te":"Noun","tt":"İsim","de":"The upper surface of a room","dt":"Bir odanın üst yüzeyi","e1":"There is a beautiful lamp on the ceiling.","e1t":"Tavanda güzel bir lamba var.","e2":"The room has a high ceiling.","e2t":"Odanın yüksek bir tavanı var."},{"w":"celebrate","tr":"kutlamak","te":"Verb","tt":"Fiil","de":"To do something special for an important event","dt":"Önemli bir olay için özel bir şey yapmak","e1":"We are going to celebrate his birthday tonight.","e1t":"Bu gece onun doğum gününü kutlayacağız.","e2":"How do you celebrate New Year?","e2t":"Yeni yılı nasıl kutlarsın?"},{"w":"celebration","tr":"kutlama","te":"Noun","tt":"İsim","de":"A special social event for a success or holiday","dt":"Başarı veya bayram için özel sosyal etkinlik","e1":"We had a big celebration for his birthday.","e1t":"Doğum günü için büyük bir kutlama yaptık.","e2":"The celebration lasted all night.","e2t":"Kutlama tüm gece sürdü."},{"w":"cell","tr":"hücre","te":"Noun","tt":"İsim","de":"The smallest unit of life or a small room","dt":"Yaşamın en küçük birimi veya küçük bir oda","e1":"The human body is made of millions of cells.","e1t":"İnsan vücudu milyonlarca hücreden oluşur.","e2":"He spent the night in a police cell.","e2t":"Geceyi bir polis hücresinde geçirdi."},{"w":"cemetery","tr":"mezarlık","te":"Noun","tt":"İsim","de":"A place where dead people are buried","dt":"Ölülerin gömüldüğü yer","e1":"He visited his grandfather's grave in the cemetery.","e1t":"Mezarlıktaki büyükbabasının mezarını ziyaret etti.","e2":"The old cemetery is very quiet.","e2t":"Eski mezarlık çok sessizdir."},{"w":"center","tr":"merkez","te":"Noun","tt":"İsim","de":"The middle point of something","dt":"Bir şeyin orta noktası","e1":"The shopping center is very big.","e1t":"Alışveriş merkezi çok büyük.","e2":"Put the vase in the center of the table.","e2t":"Vazoyu masanın ortasına koy."},{"w":"central","tr":"merkezi","te":"Adjective","tt":"Sıfat","de":"Located in the center or most important","dt":"Merkezde bulunan veya en önemli","e1":"The hotel has a central location.","e1t":"Otelin merkezi bir konumu var.","e2":"This is a central problem in the project.","e2t":"Bu, projedeki merkezi (temel) bir sorundur."},{"w":"century","tr":"yüzyıl","te":"Noun","tt":"İsim","de":"A period of 100 years","dt":"100 yıllık zaman dilimi","e1":"We are living in the 21st century.","e1t":"21. yüzyılda yaşıyoruz.","e2":"This building is five centuries old.","e2t":"Bu bina beş yüzyıllık."},{"w":"ceremony","tr":"tören","te":"Noun","tt":"İsim","de":"A formal event performed on a special occasion","dt":"Özel bir durumda gerçekleştirilen resmi etkinlik","e1":"The wedding ceremony was beautiful.","e1t":"Düğün töreni güzeldi.","e2":"He received his diploma at the graduation ceremony.","e2t":"Diplomasını mezuniyet töreninde aldı."},{"w":"certain","tr":"belirli / emin","te":"Adjective","tt":"Sıfat","de":"Being completely sure about something","dt":"Bir şeyden tamamen emin olma","e1":"I am certain that he is right.","e1t":"Onun haklı olduğundan eminim.","e2":"There are certain rules to follow.","e2t":"Uyulması gereken belirli kurallar var."},{"w":"certainly","tr":"kesinlikle","te":"Adverb","tt":"Zarf","de":"Without any doubt","dt":"Hiçbir şüphe olmaksızın","e1":"I will certainly help you.","e1t":"Sana kesinlikle yardım edeceğim.","e2":"That is certainly a great idea.","e2t":"Bu kesinlikle harika bir fikir."},{"w":"certificate","tr":"sertifika / belge","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official document that states a fact","dt":"Bir gerçeği belirten resmi belge","e1":"He received a medical certificate.","e1t":"Bir sağlık raporu (sertifikası) aldı.","e2":"You will get a certificate at the end of the course.","e2t":"Kursun sonunda bir sertifika alacaksın."},{"w":"chain","tr":"zincir","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of connected metal rings or shops","dt":"Birbirine bağlı metal halkalar dizisi veya dükkanlar","e1":"The dog is on a chain.","e1t":"Köpek bir zincire bağlı.","e2":"He owns a chain of restaurants.","e2t":"Bir restoranlar zincirinin sahibi."},{"w":"chairman","tr":"başkan","te":"Noun","tt":"İsim","de":"The person in charge of a meeting or company","dt":"Bir toplantı veya şirketin sorumlusu","e1":"The chairman opened the meeting.","e1t":"Başkan toplantıyı açtı.","e2":"He is the chairman of the board.","e2t":"Yönetim kurulu başkanıdır."},{"w":"challenge","tr":"zorluk / meydan okuma","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that is difficult and needs effort","dt":"Çaba gerektiren zor bir şey","e1":"Learning English is a challenge.","e1t":"İngilizce öğrenmek bir zorluktur (meydan okumadır).","e2":"I like a good challenge.","e2t":"İyi bir zorluğu/rekabeti severim."},{"w":"champion","tr":"şampiyon","te":"Noun","tt":"İsim","de":"A person or team that wins a competition","dt":"Bir yarışmayı kazanan kişi veya takım","e1":"Our team is the champion this year.","e1t":"Takımımız bu yıl şampiyon.","e2":"He is a world champion in swimming.","e2t":"Yüzmede dünya şampiyonudur."},{"w":"championship","tr":"şampiyona","te":"Noun","tt":"İsim","de":"A high","dt":"level competition","e1":"Üst düzey yarışma","e1t":"Who won the football championship?","e2":"Futbol şampiyonasını kim kazandı?","e2t":"The world championship will be held in Tokyo."},{"w":"chance","tr":"şans","te":"Noun","tt":"İsim","de":"An opportunity to do something","dt":"Bir şeyi yapmak için fırsat","e1":"This is your last chance.","e1t":"Bu senin son şansın.","e2":"Give me a chance to explain.","e2t":"Açıklamam için bana bir şans ver."},{"w":"change","tr":"değiştirmek / para üstü","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make different or the money returned","dt":"Farklılaştırmak veya geri verilen para","e1":"I need to change my clothes.","e1t":"Kıyafetlerimi değiştirmem gerekiyor.","e2":"Keep the change, please.","e2t":"Para üstü kalsın lütfen."},{"w":"channel","tr":"kanal","te":"Noun/Verb","tt":"İsim/Fiil","de":"A TV station or a narrow body of water","dt":"TV istasyonu veya dar su kütlesi","e1":"What is on channel 5?","e1t":"Kanal 5'te ne var?","e2":"The English Channel separates UK and France.","e2t":"Manş Denizi (Kanalı) İngiltere ve Fransa'yı ayırır."},{"w":"chapter","tr":"bölüm (kitap)","te":"Noun","tt":"İsim","de":"A separate section of a book","dt":"Bir kitabın ayrı bir bölümü","e1":"Read the first chapter of the novel.","e1t":"Romanın ilk bölümünü oku.","e2":"This is a new chapter in my life.","e2t":"Bu hayatımda yeni bir bölüm (sayfa)."},{"w":"character","tr":"karakter","te":"Noun","tt":"İsim","de":"A person in a story or someone's personality","dt":"Bir hikayedeki kişi veya birinin kişiliği","e1":"Who is your favorite character in the book?","e1t":"Kitaptaki en sevdiğin karakter kim?","e2":"He has a very strong character.","e2t":"Çok güçlü bir karakteri var."},{"w":"characteristic","tr":"özellik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A typical feature of a person or thing","dt":"Bir kişi veya şeyin tipik özelliği","e1":"Patience is his main characteristic.","e1t":"Sabır onun temel özelliğidir.","e2":"What are the characteristics of this plant?","e2t":"Bu bitkinin özellikleri nelerdir?"},{"w":"charge","tr":"ücret / şarj","te":"Noun/Verb","tt":"İsim/Fiil","de":"The price or to store electricity","dt":"Fiyat veya elektrik depolamak","e1":"Is there a charge for delivery?","e1t":"Teslimat için bir ücret var mı?","e2":"I need to charge my phone.","e2t":"Telefonumu şarj etmem gerekiyor."},{"w":"charity","tr":"hayır kurumu","te":"Noun","tt":"İsim","de":"An organization that helps people in need","dt":"İhtiyaç sahibi insanlara yardım eden kuruluş","e1":"She gives money to charity every month.","e1t":"Her ay bir hayır kurumuna para verir.","e2":"This is a local charity.","e2t":"Bu yerel bir hayır kurumudur."},{"w":"chart","tr":"çizelge","te":"Noun","tt":"İsim","de":"A drawing that shows information simply","dt":"Bilgiyi basitçe gösteren çizim","e1":"Look at the weather chart.","e1t":"Hava durumu çizelgesine bak.","e2":"The sales chart shows an increase.","e2t":"Satış çizelgesi bir artış gösteriyor."},{"w":"chase","tr":"kovalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To run after someone to catch them","dt":"Yakalamak için birinin peşinden koşmak","e1":"The cat is chasing the mouse.","e1t":"Kedi fareyi kovalıyor.","e2":"The police are in a high","e2t":"speed chase."},{"w":"chat","tr":"sohbet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To talk in a friendly and informal way","dt":"Arkadaşça ve resmi olmayan bir şekilde konuşmak","e1":"We chatted for an hour.","e1t":"Bir saat sohbet ettik.","e2":"I had a long chat with my friend.","e2t":"Arkadaşımla uzun bir sohbet ettim."},{"w":"cheap","tr":"ucuz","te":"Adjective","tt":"Sıfat","de":"Low in price","dt":"Fiyatı düşük","e1":"This watch is very cheap.","e1t":"Bu saat çok ucuz.","e2":"I want to buy a cheap flight ticket.","e2t":"Ucuz bir uçak bileti almak istiyorum."},{"w":"cheat","tr":"hile yapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To behave dishonestly to gain an advantage","dt":"Avantaj sağlamak için dürüst olmayan şekilde davranmak","e1":"Don't cheat in the exam.","e1t":"Sınavda kopya çekme (hile yapma).","e2":"He is a cheat.","e2t":"O bir hilebazdır."},{"w":"check","tr":"kontrol etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To examine something to see if it is correct","dt":"Doğru olup olmadığını görmek için incelemek","e1":"Check your answers carefully.","e1t":"Cevaplarını dikkatlice kontrol et.","e2":"Can you check the oil in the car?","e2t":"Arabanın yağını kontrol edebilir misin?"},{"w":"cheek","tr":"yanak","te":"Noun","tt":"İsim","de":"The soft part of the face below the eye","dt":"Yüzün göz altındaki yumuşak kısmı","e1":"He kissed her on the cheek.","e1t":"Onu yanağından öptü.","e2":"Her cheeks turned red.","e2t":"Yanakları kızardı."},{"w":"cheerful","tr":"neşeli","te":"Adjective","tt":"Sıfat","de":"Happy and positive","dt":"Mutlu ve pozitif","e1":"She has a cheerful personality.","e1t":"Neşeli bir kişiliği var.","e2":"It's a bright and cheerful room.","e2t":"Aydınlık ve neşeli bir oda."},{"w":"cheese","tr":"peynir","te":"Noun","tt":"İsim","de":"A food made from milk","dt":"Sütten yapılan yiyecek","e1":"I like cheese on my pizza.","e1t":"Pizzamda peyniri severim.","e2":"This cheese is very delicious.","e2t":"Bu peynir çok lezzetli."},{"w":"chemical","tr":"kimyasal","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance used in or produced by chemistry","dt":"Kimyada kullanılan veya üretilen madde","e1":"Don't use dangerous chemicals.","e1t":"Tehlikeli kimyasallar kullanmayın.","e2":"The chemical reaction was fast.","e2t":"Kimyasal reaksiyon hızlıydı."},{"w":"chemist","tr":"kimyager / eczacı","te":"Noun","tt":"İsim","de":"A person who studies chemistry or a pharmacist","dt":"Kimya okuyan kişi veya eczacı","e1":"He is a research chemist.","e1t":"O bir araştırma kimyageridir.","e2":"I need to go to the chemist (pharmacy).","e2t":"Eczaneye (eczacıya) gitmem gerekiyor."},{"w":"chemistry","tr":"kimya","te":"Noun","tt":"İsim","de":"The scientific study of substances","dt":"Maddelerin bilimsel çalışması","e1":"My favorite subject at school is chemistry.","e1t":"Okulda en sevdiğim ders kimya.","e2":"She is a chemistry teacher.","e2t":"O bir kimya öğretmeni."},{"w":"chest","tr":"göğüs / sandık","te":"Noun","tt":"İsim","de":"The upper front part of the body or a box","dt":"Vücudun üst ön kısmı veya büyük kutu","e1":"He has a pain in his chest.","e1t":"Göğsünde bir ağrı var.","e2":"The treasure was hidden in a wooden chest.","e2t":"Hazine ahşap bir sandıkta saklıydı."},{"w":"chief","tr":"şef / ana","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A leader or most important","dt":"Lider veya en önemli","e1":"He is the chief of police.","e1t":"O polis şefidir.","e2":"What is your chief concern?","e2t":"Temel (ana) endişeniz nedir?"},{"w":"child","tr":"çocuk","te":"Noun","tt":"İsim","de":"A young human being","dt":"Genç insan varlığı","e1":"Every child needs love.","e1t":"Her çocuğun sevgiye ihtiyacı vardır.","e2":"She is an only child.","e2t":"O tek çocuk."},{"w":"childhood","tr":"çocukluk","te":"Noun","tt":"İsim","de":"The period of time when you are a child","dt":"Çocuk olduğunuz zaman dilimi","e1":"I had a very happy childhood.","e1t":"Çok mutlu bir çocukluğum vardı.","e2":"They have been friends since childhood.","e2t":"Çocukluktan beri arkadaşlar."},{"w":"chin","tr":"çene (ucu)","te":"Noun","tt":"İsim","de":"The bottom part of the face below the mouth","dt":"Yüzün ağız altındaki en alt kısmı","e1":"He has a small chin.","e1t":"Küçük bir çenesi var.","e2":"Rest your chin on your hand.","e2t":"Çeneni eline daya."},{"w":"chip","tr":"çip / patates kızartması","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of material or fried potato","dt":"Küçük bir malzeme parçası veya patates kızartması","e1":"I like fish and chips.","e1t":"Balık ve patates kızartması severim.","e2":"The computer chip is very small.","e2t":"Bilgisayar çipi çok küçüktür."},{"w":"chips","tr":"patates kızartması / cips","te":"Noun","tt":"İsim","de":"Thin pieces of potato that have been fried","dt":"Kızartılmış ince patates dilimleri","e1":"I like fish and chips.","e1t":"Balık ve patates kızartmasını severim.","e2":"Potato chips.","e2t":"Patates cipsi."},{"w":"chocolate","tr":"çikolata","te":"Noun","tt":"İsim","de":"A sweet food made from cocoa","dt":"Kakao ile yapılan tatlı yiyecek","e1":"Do you want some dark chocolate?","e1t":"Biraz bitter çikolata ister misin?","e2":"I love chocolate cake.","e2t":"Çikolatalı keki severim."},{"w":"choice","tr":"seçim","te":"Noun","tt":"İsim","de":"When you choose between different things","dt":"Farklı şeyler arasında seçim yapma durumu","e1":"You have a difficult choice.","e1t":"Zor bir seçimin var.","e2":"This is my first choice.","e2t":"Bu benim ilk seçimim."},{"w":"choose","tr":"seçmek","te":"Verb","tt":"Fiil","de":"To pick something from a group","dt":"Bir gruptan bir şeyi almak/seçmek","e1":"Please choose a color.","e1t":"Lütfen bir renk seçin.","e2":"I don't know which one to choose.","e2t":"Hangisini seçeceğimi bilmiyorum."},{"w":"chop","tr":"doğramak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cut into pieces with a knife","dt":"Bıçakla parçalara bölmek","e1":"Chop the onions finely.","e1t":"Soğanları ince ince doğra.","e2":"He is chopping wood for the fire.","e2t":"Ateş için odun kesiyor (doğruyor)."},{"w":"church","tr":"kilise","te":"Noun","tt":"İsim","de":"A building where Christians go to pray","dt":"Hristiyanların dua etmek için gittiği bina","e1":"There is a beautiful church in the village.","e1t":"Köyde güzel bir kilise var.","e2":"They go to church every Sunday.","e2t":"Her pazar kiliseye giderler."},{"w":"cigarette","tr":"sigara","te":"Noun","tt":"İsim","de":"A thin tube of paper filled with tobacco","dt":"Tütünle doldurulmuş ince kağıt tüp","e1":"He lit a cigarette.","e1t":"Bir sigara yaktı.","e2":"Smoking cigarettes is bad for your health.","e2t":"Sigara içmek sağlığınız için kötüdür."},{"w":"cinema","tr":"sinema","te":"Noun","tt":"İsim","de":"A place where films are shown","dt":"Filmlerin gösterildiği yer","e1":"Let's go to the cinema tonight.","e1t":"Bu gece sinemaya gidelim.","e2":"What is on at the cinema?","e2t":"Sinemada ne var?"},{"w":"circle","tr":"daire","te":"Noun","tt":"İsim","de":"A perfectly round shape","dt":"Tamamen yuvarlak bir şekil","e1":"Draw a circle on the paper.","e1t":"Kağıda bir daire çiz.","e2":"We sat in a circle.","e2t":"Bir daire şeklinde oturduk."},{"w":"circular","tr":"dairesel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Shaped like a circle or a notice","dt":"Daire şeklinde veya duyuru/ilan","e1":"The table is circular.","e1t":"Masa daireseldir (yuvarlaktır).","e2":"We received a circular from the school.","e2t":"Okuldan bir duyuru (sirküler) aldık."},{"w":"circumstance","tr":"durum / koşul","te":"Noun","tt":"İsim","de":"A fact or condition connected with an event","dt":"Bir olayla bağlantılı gerçek veya koşul","e1":"Under no circumstances should you leave.","e1t":"Hiçbir koşulda ayrılmamalısın.","e2":"The circumstances have changed.","e2t":"Koşullar değişti."},{"w":"citizen","tr":"vatandaş","te":"Noun","tt":"İsim","de":"A person who lives in a particular city or country","dt":"Belirli bir şehir veya ülkede yaşayan kişi","e1":"He is a Turkish citizen.","e1t":"O bir Türk vatandaşıdır.","e2":"Good citizens follow the law.","e2t":"İyi vatandaşlar yasalara uyar."},{"w":"city center","tr":"şehir merkezi","te":"Noun","tt":"İsim","de":"The main business or shopping area of a city","dt":"Bir şehrin ana iş veya alışveriş alanı","e1":"The hotel is in the city center.","e1t":"Otel şehir merkezindedir.","e2":"I don't like driving in the city center.","e2t":"Şehir merkezinde araba sürmeyi sevmem."},{"w":"civil","tr":"sivil / medeni","te":"Adjective","tt":"Sıfat","de":"Relating to ordinary citizens or polite","dt":"Sıradan vatandaşlarla ilgili veya nazik","e1":"They are fighting for civil rights.","e1t":"Sivil haklar için savaşıyorlar.","e2":"It was a civil ceremony.","e2t":"Sivil (resmi) bir törendi."},{"w":"claim","tr":"iddia etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say that something is true without proof","dt":"Kanıt olmadan bir şeyin doğru olduğunu söylemek","e1":"He claims that he saw a UFO.","e1t":"Bir UFO gördüğünü iddia ediyor.","e2":"They made a claim for the insurance.","e2t":"Sigorta için talepte (iddiada) bulundular."},{"w":"class","tr":"sınıf","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of students or a social rank","dt":"Öğrenci grubu veya sosyal rütbe","e1":"I have an English class at 9 AM.","e1t":"Sabah 9'da İngilizce dersim (sınıfım) var.","e2":"We belong to the middle class.","e2t":"Orta sınıfa aitiz."},{"w":"classic","tr":"klasik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Traditional in style and of high quality","dt":"Stil olarak geleneksel ve yüksek kaliteli","e1":"I love reading classic novels.","e1t":"Klasik romanlar okumayı severim.","e2":"This is a classic example of the problem.","e2t":"Bu, sorunun klasik bir örneğidir."},{"w":"classical","tr":"klasik (müzik vb.)","te":"Adjective","tt":"Sıfat","de":"Relating to traditional culture or music","dt":"Geleneksel kültür veya müzikle ilgili","e1":"He enjoys listening to classical music.","e1t":"Klasik müzik dinlemekten zevk alır.","e2":"She is a classical dancer.","e2t":"O bir klasik dansçıdır."},{"w":"cleaner","tr":"temizlikçi / temizleyici","te":"Noun","tt":"İsim","de":"A person or thing that cleans","dt":"Temizleyen kişi veya şey","e1":"The window cleaner is here.","e1t":"Cam temizleyicisi burada.","e2":"Vacuum cleaner is very useful.","e2t":"Elektrikli süpürge (vakumlu temizleyici) çok yararlıdır."},{"w":"clear","tr":"açık / net","te":"Adjective/Verb","tt":"Easy to see or understand","de":"Görmesi veya anlaması kolay","dt":"Is the meaning clear?","e1":"Anlam açık mı?","e1t":"The sky is clear today.","e2":"Bugün gökyüzü açık (bulutsuz).","e2t":""},{"w":"clearly","tr":"açıkça","te":"Adverb","tt":"Zarf","de":"In a way that is easy to see or understand","dt":"Görmesi veya anlaması kolay bir şekilde","e1":"Speak clearly, please.","e1t":"Açıkça konuşun lütfen.","e2":"He clearly explained the rules.","e2t":"Kuralları net bir şekilde açıkladı."},{"w":"clerk","tr":"memur / tezgahtar","te":"Noun","tt":"İsim","de":"A person who works in an office or shop","dt":"Ofiste veya dükkanda çalışan kişi","e1":"Talk to the hotel clerk.","e1t":"Otel görevlisiyle (memuruyla) konuşun.","e2":"He works as a bank clerk.","e2t":"Banka memuru olarak çalışıyor."},{"w":"clever","tr":"zeki","te":"Adjective","tt":"Sıfat","de":"Intelligent and able to learn quickly","dt":"Zeki ve hızlı öğrenebilen","e1":"He is a very clever child.","e1t":"Çok zeki bir çocuktur.","e2":"That was a clever trick.","e2t":"Bu zekice bir hileydi."},{"w":"click","tr":"tıklamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To press a button on a mouse or a sound","dt":"Fare butonuna basmak veya bir ses (tık)","e1":"Click on the link to open the file.","e1t":"Dosyayı açmak için bağlantıya tıkla.","e2":"I heard a loud click.","e2t":"Sert bir tık sesi duydum."},{"w":"client","tr":"müvekkil / müşteri","te":"Noun","tt":"İsim","de":"A person who uses professional services","dt":"Profesyonel hizmet kullanan kişi","e1":"The lawyer is meeting a new client.","e1t":"Avukat yeni bir müvekkille görüşüyor.","e2":"Our clients are very satisfied.","e2t":"Müşterilerimiz çok memnun."},{"w":"climate","tr":"iklim","te":"Noun","tt":"İsim","de":"The general weather conditions of a place","dt":"Bir yerin genel hava koşulları","e1":"The climate is changing.","e1t":"İklim değişiyor.","e2":"Antalya has a warm climate.","e2t":"Antalya'nın sıcak bir iklimi var."},{"w":"climb","tr":"tırmanmak","te":"Verb","tt":"Fiil","de":"To go up something towards the top","dt":"Bir şeyin tepesine doğru yukarı gitmek","e1":"We want to climb Mount Ararat.","e1t":"Ağrı Dağı'na tırmanmak istiyoruz.","e2":"The cat climbed the tree.","e2t":"Kedi ağaca tırmandı."},{"w":"climbing","tr":"tırmanış","te":"Noun","tt":"İsim","de":"The sport or activity of going up","dt":"Yukarı çıkma sporu veya faaliyeti","e1":"Rock climbing is dangerous.","e1t":"Kaya tırmanışı tehlikelidir.","e2":"We went climbing last weekend.","e2t":"Geçen hafta sonu tırmanışa gittik."},{"w":"clock","tr":"saat (duvar/masa)","te":"Noun","tt":"İsim","de":"A device that shows time","dt":"Zamanı gösteren cihaz","e1":"Look at the clock on the wall.","e1t":"Duvardaki saate bak.","e2":"The alarm clock rang at 6 AM.","e2t":"Çalar saat sabah 6'da çaldı."},{"w":"closed","tr":"kapalı","te":"Adjective","tt":"Sıfat","de":"Not open","dt":"Açık olmayan","e1":"The shop is closed today.","e1t":"Dükkan bugün kapalı.","e2":"Keep the windows closed.","e2t":"Pencereleri kapalı tutun."},{"w":"closely","tr":"yakından","te":"Adverb","tt":"Zarf","de":"In a careful way or near in distance","dt":"Dikkatli bir şekilde veya mesafece yakın","e1":"Follow the instructions closely.","e1t":"Talimatları yakından (dikkatle) takip et.","e2":"They are working closely together.","e2t":"Birlikte yakından çalışıyorlar."},{"w":"cloth","tr":"kumaş","te":"Noun","tt":"İsim","de":"Material used for making clothes","dt":"Kıyafet yapmak için kullanılan malzeme","e1":"Clean the table with a wet cloth.","e1t":"Masayı ıslak bir bezle (kumaşla) temizle.","e2":"I need a piece of cotton cloth.","e2t":"Bir parça pamuklu kumaşa ihtiyacım var."},{"w":"clothing","tr":"giyim","te":"Noun","tt":"İsim","de":"Clothes in general","dt":"Genel anlamda kıyafetler","e1":"Wear warm clothing in winter.","e1t":"Kışın sıcak tutan giysiler giyin.","e2":"The store sells protective clothing.","e2t":"Mağaza koruyucu giysi satıyor."},{"w":"club","tr":"kulüp","te":"Noun","tt":"İsim","de":"An organization for people with shared interests","dt":"Ortak ilgi alanları olan insanlar için organizasyon","e1":"He is a member of the chess club.","e1t":"Satranç kulübünün bir üyesidir.","e2":"Let's go to the dance club.","e2t":"Dans kulübüne gidelim."},{"w":"clue","tr":"ipucu","te":"Noun","tt":"İsim","de":"Information that helps solve a problem","dt":"Bir sorunu çözmeye yardımcı olan bilgi","e1":"The police found a clue at the scene.","e1t":"Polis olay yerinde bir ipucu buldu.","e2":"I don't have a clue!","e2t":"Hiçbir fikrim (ipucum) yok!"},{"w":"coach","tr":"antrenör / otobüs","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who trains a team or a bus","dt":"Takım eğiten kişi veya yolcu otobüsü","e1":"He is a football coach.","e1t":"O bir futbol antrenörüdür.","e2":"We traveled to London by coach.","e2t":"Londra'ya şehirlerarası otobüsle (coach) seyahat ettik."},{"w":"coal","tr":"kömür","te":"Noun","tt":"İsim","de":"A hard black substance used as fuel","dt":"Yakıt olarak kullanılan sert siyah madde","e1":"They use coal for heating.","e1t":"Isınma için kömür kullanıyorlar.","e2":"He works in a coal mine.","e2t":"Bir kömür madeninde çalışıyor."},{"w":"coast","tr":"sahil","te":"Noun","tt":"İsim","de":"The land next to or close to the sea","dt":"Denizin yanındaki veya yakınındaki kara","e1":"We live near the west coast.","e1t":"Batı sahilinin yakınında yaşıyoruz.","e2":"They walked along the coast.","e2t":"Sahil boyunca yürüdüler."},{"w":"code","tr":"kod","te":"Noun/Verb","tt":"İsim/Fiil","de":"A system of words, letters, or symbols","dt":"Kelime, harf veya semboller sistemi","e1":"What is the area code for Istanbul?","e1t":"İstanbul'un alan kodu nedir?","e2":"He is learning how to write computer code.","e2t":"Bilgisayar kodu yazmayı öğreniyor."},{"w":"coin","tr":"madeni para","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat round piece of metal used as money","dt":"Para olarak kullanılan düz yuvarlak metal parça","e1":"I have some coins in my pocket.","e1t":"Cebimde biraz madeni para var.","e2":"He collects ancient coins.","e2t":"Antik paralar topluyor."},{"w":"collapse","tr":"çökmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fall down suddenly","dt":"Aniden yere düşmek (yıkılmak)","e1":"The building collapsed during the earthquake.","e1t":"Bina deprem sırasında çöktü.","e2":"He collapsed from exhaustion.","e2t":"Yorgunluktan bayıldı (çöktü)."},{"w":"collect","tr":"toplamak","te":"Verb","tt":"Fiil","de":"To bring things together from different places","dt":"Farklı yerlerden şeyleri bir araya getirmek","e1":"He collects old coins.","e1t":"Eski madeni paraları topluyor.","e2":"I need to collect my luggage.","e2t":"Bagajımı almam (toplamam) gerekiyor."},{"w":"collection","tr":"koleksiyon","te":"Noun","tt":"İsim","de":"A group of objects brought together","dt":"Bir araya getirilmiş nesneler grubu","e1":"The museum has a famous art collection.","e1t":"Müzenin ünlü bir sanat koleksiyonu var.","e2":"My coin collection is growing.","e2t":"Madeni para koleksiyonum büyüyor."},{"w":"college","tr":"kolej / yüksekokul","te":"Noun","tt":"İsim","de":"A place for higher education","dt":"Yüksek eğitim yeri","e1":"She is going to college next year.","e1t":"Gelecek yıl koleje/yüksekokula gidiyor.","e2":"He teaches history at a local college.","e2t":"Yerel bir kolejde tarih dersi veriyor."},{"w":"colored","tr":"renkli","te":"Adjective","tt":"Sıfat","de":"Having a particular color","dt":"Belirli bir rengi olan","e1":"Use a colored pencil for the drawing.","e1t":"Çizim için renkli bir kalem kullan.","e2":"She wore a brightly colored dress.","e2t":"Parlak renkli bir elbise giydi."},{"w":"column","tr":"sütun","te":"Noun","tt":"İsim","de":"A vertical block of text or a stone pillar","dt":"Metnin dikey bloğu veya taş sütun","e1":"Read the second column of the table.","e1t":"Tablonun ikinci sütununu oku.","e2":"The building has many Greek columns.","e2t":"Binanın birçok Yunan sütunu var."},{"w":"comb","tr":"tarak / taramak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for making hair tidy","dt":"Saçı düzeltmek için kullanılan araç","e1":"Where is my comb?","e1t":"Tarağım nerede?","e2":"Comb your hair.","e2t":"Saçını tara."},{"w":"combination","tr":"kombinasyon / birleşim","te":"Noun","tt":"İsim","de":"A mix of different things","dt":"Farklı şeylerin karışımı","e1":"The salad is a combination of fruits.","e1t":"Salata meyvelerin bir birleşimidir.","e2":"What is the combination for the lock?","e2t":"Kilidin şifresi (kombinasyonu) nedir?"},{"w":"combine","tr":"birleştirmek","te":"Verb","tt":"Fiil","de":"To join two or more things together","dt":"İki veya daha fazla şeyi bir araya getirmek","e1":"Combine the flour and water.","e1t":"Un ve suyu birleştirin.","e2":"We need to combine our efforts.","e2t":"Çabalarımızı birleştirmeliyiz."},{"w":"comedy","tr":"komedi","te":"Noun","tt":"İsim","de":"A funny movie, play, or show","dt":"Komik film, oyun veya gösteri","e1":"I love watching romantic comedies.","e1t":"Romantik komediler izlemeyi severim.","e2":"The show was a great comedy.","e2t":"Gösteri harika bir komediydi."},{"w":"comfort","tr":"konfor / rahatlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A state of physical ease","dt":"Fiziksel rahatlık durumu","e1":"I like the comfort of my own bed.","e1t":"Kendi yatağımın rahatlığını severim.","e2":"She tried to comfort the crying child.","e2t":"Ağlayan çocuğu teselli etmeye (rahatlatmaya) çalıştı."},{"w":"comfortable","tr":"rahat","te":"Adjective","tt":"Sıfat","de":"Making you feel physically relaxed","dt":"Fiziksel olarak rahatlamış hissettiren","e1":"This sofa is very comfortable.","e1t":"Bu kanepe çok rahat.","e2":"Wear comfortable shoes for walking.","e2t":"Yürüyüş için rahat ayakkabılar giy."},{"w":"command","tr":"komut / emir","te":"Noun/Verb","tt":"İsim/Fiil","de":"An order given by a person in authority","dt":"Yetkili bir kişi tarafından verilen emir","e1":"The soldiers followed the command.","e1t":"Askerler emri (komutu) takip etti.","e2":"He has a good command of English.","e2t":"İyi bir İngilizce hakimiyeti (komutası) var."},{"w":"comment","tr":"yorum","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that you say or write to give an opinion","dt":"Görüş bildirmek için söylenen veya yazılan şey","e1":"Do you have any comments about the plan?","e1t":"Plan hakkında herhangi bir yorumunuz var mı?","e2":"He commented on my new photo.","e2t":"Yeni fotoğrafıma yorum yaptı."},{"w":"commercial","tr":"ticari / reklam","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to business or a TV advertisement","dt":"İş dünyasıyla ilgili veya TV reklamı","e1":"It was a commercial success.","e1t":"Ticari bir başarıydı.","e2":"I hate watching TV commercials.","e2t":"TV reklamlarını izlemekten nefret ederim."},{"w":"commission","tr":"komisyon","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal task or a payment for a sale","dt":"Resmi bir görev veya satış için yapılan ödeme","e1":"He earns a 10% commission on every sale.","e1t":"Her satıştan %10 komisyon kazanıyor.","e2":"The government set up a commission.","e2t":"Hükümet bir komisyon kurdu."},{"w":"commit","tr":"işlemek (suç vb.) / adamak","te":"Verb","tt":"Fiil","de":"To do something wrong or to dedicate","dt":"Yanlış bir şey yapmak veya kendini adamak","e1":"He committed a serious crime.","e1t":"Ciddi bir suç işledi.","e2":"You need to commit yourself to the job.","e2t":"Kendini işe adamalısın."},{"w":"commitment","tr":"bağlılık / taahhüt","te":"Noun","tt":"İsim","de":"A promise to do something","dt":"Bir şeyi yapma sözü","e1":"Marriage is a big commitment.","e1t":"Evlilik büyük bir bağlılıktır.","e2":"I have too many commitments this week.","e2t":"Bu hafta çok fazla taahhüdüm (işim) var."},{"w":"committee","tr":"komite","te":"Noun","tt":"İsim","de":"A group of people chosen to make decisions","dt":"Karar vermek için seçilen insan grubu","e1":"The committee will meet tomorrow.","e1t":"Komite yarın toplanacak.","e2":"He is the head of the organizing committee.","e2t":"Organizasyon komitesinin başkanıdır."},{"w":"common","tr":"yaygın / ortak","te":"Adjective","tt":"Sıfat","de":"Usual or shared by many","dt":"Olağan veya birçok kişi tarafından paylaşılan","e1":"This is a common mistake.","e1t":"Bu yaygın bir hatadır.","e2":"We have a common interest in music.","e2t":"Müziğe ortak bir ilgimiz var."},{"w":"commonly","tr":"yaygın olarak","te":"Adverb","tt":"Zarf","de":"Often or usually","dt":"Sık sık veya genellikle","e1":"This word is commonly used in English.","e1t":"Bu kelime İngilizcede yaygın olarak kullanılır.","e2":"It is commonly believed that...","e2t":"Yaygın olarak ... inanılır."},{"w":"communicate","tr":"iletişim kurmak","te":"Verb","tt":"Fiil","de":"To share information with others","dt":"Başkalarıyla bilgi paylaşmak","e1":"We communicate by email.","e1t":"E","e2":"posta yoluyla iletişim kuruyoruz.","e2t":"It is important to communicate clearly."},{"w":"communication","tr":"iletişim","te":"Noun","tt":"İsim","de":"The act of sharing information","dt":"Bilgi paylaşma eylemi","e1":"Good communication is key to success.","e1t":"İyi iletişim başarının anahtarıdır.","e2":"Radio was a major communication tool.","e2t":"Radyo ana bir iletişim aracıydı."},{"w":"community","tr":"topluluk","te":"Noun","tt":"İsim","de":"A group of people living in the same area","dt":"Aynı bölgede yaşayan bir grup insan","e1":"We have a very friendly community here.","e1t":"Burada çok arkadaş canlısı bir topluluğumuz var.","e2":"He is a leader in the local community.","e2t":"Yerel toplulukta bir liderdir."},{"w":"compare","tr":"karşılaştırmak","te":"Verb","tt":"Fiil","de":"To examine things to see how they are different","dt":"Şeylerin nasıl farklı olduğunu görmek için incelemek","e1":"Don't compare yourself with others.","e1t":"Kendini başkalarıyla karşılaştırma.","e2":"Compare the prices before you buy.","e2t":"Satın almadan önce fiyatları karşılaştır."},{"w":"comparison","tr":"karşılaştırma","te":"Noun","tt":"İsim","de":"The act of comparing","dt":"Karşılaştırma eylemi","e1":"By comparison, the second movie was better.","e1t":"Karşılaştırıldığında, ikinci film daha iyiydi.","e2":"There is no comparison between them.","e2t":"Aralarında bir karşılaştırma (kıyas) yapılamaz."},{"w":"compete","tr":"yarışmak","te":"Verb","tt":"Fiil","de":"To try to win against others","dt":"Başkalarına karşı kazanmaya çalışmak","e1":"Athletes from 50 countries will compete.","e1t":"50 ülkeden sporcular yarışacak.","e2":"It is difficult to compete with large companies.","e2t":"Büyük şirketlerle yarışmak zordur."},{"w":"competition","tr":"yarışma","te":"Noun","tt":"İsim","de":"An event where people try to win something","dt":"İnsanların bir şeyi kazanmaya çalıştığı etkinlik","e1":"He won the swimming competition.","e1t":"Yüzme yarışmasını kazandı.","e2":"There is a lot of competition in business.","e2t":"İş dünyasında çok fazla rekabet (yarışma) var."},{"w":"competitive","tr":"rekabetçi","te":"Adjective","tt":"Sıfat","de":"Wanting to be more successful than others","dt":"Diğerlerinden daha başarılı olmak isteme","e1":"He is a very competitive person.","e1t":"O çok rekabetçi biridir.","e2":"We offer competitive prices.","e2t":"Rekabetçi fiyatlar sunuyoruz."},{"w":"competitor","tr":"rakip","te":"Noun","tt":"İsim","de":"A person or team that competes","dt":"Yarışan kişi veya takım","e1":"Our main competitor is a local firm.","e1t":"Ana rakibimiz yerel bir firma.","e2":"There were ten competitors in the race.","e2t":"Yarışta on rakip vardı."},{"w":"complain","tr":"şikayet etmek","te":"Verb","tt":"Fiil","de":"To say that something is wrong or not good","dt":"Bir şeyin yanlış veya iyi olmadığını söylemek","e1":"I want to complain about the service.","e1t":"Hizmet hakkında şikayet etmek istiyorum.","e2":"He never complains about his job.","e2t":"İşi hakkında asla şikayet etmez."},{"w":"complaint","tr":"şikayet","te":"Noun","tt":"İsim","de":"A statement that you are unhappy with something","dt":"Bir şeyden memnuniyetsiz olduğunuzu belirten ifade","e1":"We received a complaint from a customer.","e1t":"Bir müşteriden şikayet aldık.","e2":"Make a formal complaint if you are not happy.","e2t":"Mutlu değilsen resmi bir şikayette bulun."},{"w":"complete","tr":"tamamlamak","te":"Verb/Adjective","tt":"To finish doing something or make it whole","de":"Bir şeyi yapmayı bitirmek veya bütünlemek","dt":"Please complete the form.","e1":"Lütfen formu tamamlayın.","e1t":"The project is now complete.","e2":"Proje şu an tamamlandı (tam).","e2t":""},{"w":"completely","tr":"tamamen","te":"Adverb","tt":"Zarf","de":"Totally or perfectly","dt":"Bütünüyle veya kusursuzca","e1":"I completely agree with you.","e1t":"Sana tamamen katılıyorum.","e2":"The building was completely destroyed.","e2t":"Bina tamamen yıkıldı."},{"w":"complex","tr":"karmaşık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Difficult to understand or a group of buildings","dt":"Anlaşılması zor veya binalar grubu","e1":"The human brain is very complex.","e1t":"İnsan beyni çok karmaşıktır.","e2":"We live in a modern apartment complex.","e2t":"Modern bir apartman kompleksinde yaşıyoruz."},{"w":"complicated","tr":"karmaşık","te":"Adjective","tt":"Sıfat","de":"Difficult to understand or deal with","dt":"Anlaması veya uğraşması zor","e1":"The rules of the game are very complicated.","e1t":"Oyunun kuralları çok karmaşık.","e2":"It is a complicated situation.","e2t":"Karmaşık bir durum."},{"w":"component","tr":"bileşen","te":"Noun","tt":"İsim","de":"One of the parts of a system","dt":"Bir sistemin parçalarından biri","e1":"Nitrogen is a major component of air.","e1t":"Azot, havanın ana bileşenlerinden biridir.","e2":"We need to replace a small component.","e2t":"Küçük bir bileşeni değiştirmemiz gerekiyor."},{"w":"concentrate","tr":"odaklanmak","te":"Verb","tt":"Fiil","de":"To give all your attention to something","dt":"Tüm dikkatinizi bir şeye vermek","e1":"I can't concentrate with this noise.","e1t":"Bu gürültüyle odaklanamıyorum.","e2":"Concentrate on your studies.","e2t":"Derslerine odaklan."},{"w":"concentration","tr":"konsantrasyon / yoğunluk","te":"Noun","tt":"İsim","de":"The act of focusing or the amount of a substance","dt":"Odaklanma eylemi veya bir maddenin miktarı","e1":"This task requires great concentration.","e1t":"Bu görev büyük konsantrasyon gerektirir.","e2":"There is a high concentration of salt in the sea.","e2t":"Denizde yüksek bir tuz konsantrasyonu (yoğunluğu) var."},{"w":"concept","tr":"kavram","te":"Noun","tt":"İsim","de":"An abstract idea or principle","dt":"Soyut bir fikir veya ilke","e1":"He introduced a new marketing concept.","e1t":"Yeni bir pazarlama kavramı sundu.","e2":"Do you understand the basic concept?","e2t":"Temel kavramı anlıyor musun?"},{"w":"concern","tr":"endişe / ilgilendirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of worry or to be about","dt":"Endişe hissi veya ... ile ilgili olmak","e1":"My main concern is your safety.","e1t":"Ana endişem senin güvenliğin.","e2":"This matter does not concern you.","e2t":"Bu mesele seni ilgilendirmez."},{"w":"concerned","tr":"endişeli / ilgili","te":"Adjective","tt":"Sıfat","de":"Worried or involved","dt":"Endişeli veya dahil olmuş","e1":"I am concerned about his health.","e1t":"Onun sağlığı hakkında endişeliyim.","e2":"All concerned parties were present.","e2t":"Tüm ilgili taraflar oradaydı."},{"w":"concerning","tr":"hakkında / ile ilgili","te":"Preposition","tt":"Edat","de":"About or relating to","dt":"Hakkında veya ... ile ilgili","e1":"He wrote a letter concerning the new project.","e1t":"Yeni proje hakkında bir mektup yazdı.","e2":"I have some questions concerning the schedule.","e2t":"Programla ilgili bazı sorularım var."},{"w":"concert","tr":"konser","te":"Noun","tt":"İsim","de":"A musical performance","dt":"Müzikal performans","e1":"We are going to a rock concert tonight.","e1t":"Bu gece bir rock konserine gidiyoruz.","e2":"The concert was held in the open air.","e2t":"Konser açık havada yapıldı."},{"w":"conclude","tr":"sonuçlandırmak","te":"Verb","tt":"Fiil","de":"To bring to an end or to decide","dt":"Bir sona ulaştırmak veya karar vermek","e1":"The meeting concluded at 5 PM.","e1t":"Toplantı saat 5'te sona erdi.","e2":"I concluded that he was right.","e2t":"Onun haklı olduğu sonucuna vardım."},{"w":"conclusion","tr":"sonuç","te":"Noun","tt":"İsim","de":"The end or a final decision","dt":"Son veya nihai karar","e1":"In conclusion, I would like to thank you.","e1t":"Sonuç olarak (bitirirken), size teşekkür etmek isterim.","e2":"We reached the same conclusion.","e2t":"Aynı sonuca vardık."},{"w":"concrete","tr":"beton / somut","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard building material or real/solid","dt":"Sert inşaat malzemesi veya gerçek/katı","e1":"The floor is made of concrete.","e1t":"Zemin betondan yapılmıştır.","e2":"Can you give me a concrete example?","e2t":"Bana somut bir örnek verebilir misin?"},{"w":"condition","tr":"durum","te":"Noun","tt":"İsim","de":"The state that something is in","dt":"Bir şeyin içinde bulunduğu hal","e1":"The car is in very good condition.","e1t":"Araba çok iyi durumda.","e2":"Living conditions are improving.","e2t":"Yaşam koşulları iyileşiyor."},{"w":"conduct","tr":"yürütmek / davranış","te":"Verb/Noun","tt":"Fiil/İsim","de":"To organize an activity or someone's behavior","dt":"Bir faaliyeti organize etmek veya davranış","e1":"They are conducting a survey.","e1t":"Bir anket yürütüyorlar (yapıyorlar).","e2":"His conduct during the meeting was professional.","e2t":"Toplantı sırasındaki davranışı profesyonelceydi."},{"w":"conference","tr":"konferans","te":"Noun","tt":"İsim","de":"A large formal meeting for discussion","dt":"Tartışma için yapılan büyük resmi toplantı","e1":"He is attending a medical conference.","e1t":"Bir tıp konferansına katılıyor.","e2":"The conference was very useful.","e2t":"Konferans çok yararlıydı."},{"w":"confidence","tr":"güven","te":"Noun","tt":"İsim","de":"A feeling of trust or belief in oneself","dt":"Birine duyulan güven veya kendine güven","e1":"I have confidence in your ability.","e1t":"Senin yeteneğine güvenim var.","e2":"He answered the questions with confidence.","e2t":"Soruları güvenle (kendinden emin bir şekilde) cevapladı."},{"w":"confident","tr":"kendinden emin","te":"Adjective","tt":"Sıfat","de":"Feeling sure about oneself or something","dt":"Kendinden veya bir şeyden emin hissetme","e1":"She is a confident speaker.","e1t":"O kendinden emin bir konuşmacıdır.","e2":"I am confident that we will win.","e2t":"Kazanacağımızdan eminim."},{"w":"confirm","tr":"onaylamak / teyit etmek","te":"Verb","tt":"Fiil","de":"To state that something is definitely true","dt":"Bir şeyin kesinlikle doğru olduğunu belirtmek","e1":"Please confirm your flight.","e1t":"Lütfen uçuşunuzu teyit edin.","e2":"The results confirmed my suspicions.","e2t":"Sonuçlar şüphelerimi doğruladı (teyit etti)."},{"w":"confirmation","tr":"onay","te":"Noun","tt":"İsim","de":"A statement that something is definitely true","dt":"Bir şeyin kesinlikle doğru olduğuna dair ifade","e1":"I am waiting for the confirmation email.","e1t":"Onay e","e2":"postasını bekliyorum.","e2t":"We need a written confirmation."},{"w":"conflict","tr":"çatışma","te":"Noun/Verb","tt":"İsim/Fiil","de":"A serious disagreement or argument","dt":"Ciddi bir anlaşmazlık veya tartışma","e1":"There is a conflict between the two countries.","e1t":"İki ülke arasında bir çatışma var.","e2":"I have a conflict in my schedule.","e2t":"Programımda bir çakışma (çatışma) var."},{"w":"confuse","tr":"karıştırmak","te":"Verb","tt":"Fiil","de":"To make someone unable to think clearly","dt":"Birinin net düşünememesine neden olmak","e1":"Don't confuse the two brothers.","e1t":"İki kardeşi birbirine karıştırma.","e2":"The new rules confused everyone.","e2t":"Yeni kurallar herkesin kafasını karıştırdı."},{"w":"confused","tr":"kafası karışmış","te":"Adjective","tt":"Sıfat","de":"Unable to think clearly","dt":"Net düşünememe durumu","e1":"I am a bit confused about the dates.","e1t":"Tarihler konusunda biraz kafam karıştı.","e2":"He looked confused by the question.","e2t":"Soru karşısında kafası karışmış göründü."},{"w":"confusing","tr":"kafa karıştırıcı","te":"Adjective","tt":"Sıfat","de":"Difficult to understand","dt":"Anlaşılması zor","e1":"The instructions are very confusing.","e1t":"Talimatlar çok kafa karıştırıcı.","e2":"It was a confusing situation.","e2t":"Kafa karıştırıcı bir durumdu."},{"w":"confusion","tr":"kafa karışıklığı","te":"Noun","tt":"İsim","de":"A state of not being clear","dt":"Net olmama durumu","e1":"There was some confusion about the price.","e1t":"Fiyat hakkında bir kafa karışıklığı vardı.","e2":"The news caused great confusion.","e2t":"Haberler büyük kafa karışıklığına yol açtı."},{"w":"congratulate","tr":"tebrik etmek","te":"Verb","tt":"Fiil","de":"To tell someone you are happy for their success","dt":"Birine başarısından dolayı mutlu olduğunuzu söylemek","e1":"I want to congratulate you on your promotion.","e1t":"Terfinizden dolayı sizi tebrik etmek istiyorum.","e2":"He congratulated the winner.","e2t":"Kazananı tebrik etti."},{"w":"congratulations","tr":"tebrikler","te":"Noun","tt":"İsim","de":"Expressions of praise for an achievement","dt":"Bir başarı için övgü ifadeleri","e1":"Congratulations on your wedding!","e1t":"Düğününüz için tebrikler!","e2":"Give him my congratulations.","e2t":"Ona tebriklerimi ilet."},{"w":"connect","tr":"bağlamak","te":"Verb","tt":"Fiil","de":"To join two or more things together","dt":"İki veya daha fazla şeyi birleştirmek","e1":"Connect the printer to the computer.","e1t":"Yazıcıyı bilgisayara bağla.","e2":"This road connects the two cities.","e2t":"Bu yol iki şehri birbirine bağlar."},{"w":"connection","tr":"bağlantı","te":"Noun","tt":"İsim","de":"A state in which things are joined","dt":"Şeylerin birleşmiş olma durumu","e1":"My internet connection is very slow.","e1t":"İnternet bağlantım çok yavaş.","e2":"There is no connection between the two events.","e2t":"İki olay arasında hiçbir bağlantı yok."},{"w":"conscious","tr":"bilinçli","te":"Adjective","tt":"Sıfat","de":"Awake and aware of one's surroundings","dt":"Uyanık ve çevresinin farkında olma","e1":"He was still conscious after the accident.","e1t":"Kazadan sonra hâlâ bilinci yerindeydi.","e2":"She is very health","e2t":"conscious."},{"w":"consequence","tr":"sonuç","te":"Noun","tt":"İsim","de":"A result of a particular action","dt":"Belirli bir eylemin sonucu","e1":"You must accept the consequences.","e1t":"Sonuçları kabul etmelisin.","e2":"The error had serious consequences.","e2t":"Hatanın ciddi sonuçları oldu."},{"w":"conservative","tr":"muhafazakar","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Preferring traditional values","dt":"Geleneksel değerleri tercih eden","e1":"He has a conservative lifestyle.","e1t":"Muhafazakar bir yaşam tarzı var.","e2":"She wore a conservative suit to the interview.","e2t":"Mülakata klasik (muhafazakar) bir takım elbiseyle gitti."},{"w":"consider","tr":"düşünmek","te":"Verb","tt":"Fiil","de":"To think carefully about something","dt":"Bir şey hakkında dikkatlice düşünmek","e1":"We are considering moving to Izmir.","e1t":"İzmir'ye taşınmayı düşünüyoruz.","e2":"Consider all the options.","e2t":"Tüm seçenekleri değerlendir (düşün)."},{"w":"consideration","tr":"düşünme / husus","te":"Noun","tt":"İsim","de":"Careful thought or a fact taken into account","dt":"Dikkatli düşünme veya hesaba katılan gerçek","e1":"After careful consideration, I decided to go.","e1t":"Dikkatli bir düşünmeden sonra gitmeye karar verdim.","e2":"Safety is our main consideration.","e2t":"Güvenlik bizim ana hususumuzdur (dikkate aldığımız şeydir)."},{"w":"consist","tr":"oluşmak","te":"Verb","tt":"Fiil","de":"To be made up of","dt":"...","e1":"den oluşmak","e1t":"The team consists of ten members.","e2":"Takım on üyeden oluşur.","e2t":"A healthy diet consists of fruits and vegetables."},{"w":"consistent","tr":"tutarlı","te":"Adjective","tt":"Sıfat","de":"Always behaving or happening in a similar way","dt":"Her zaman benzer şekilde davranan veya gerçekleşen","e1":"You need to be consistent in your work.","e1t":"Çalışmanda tutarlı olmalısın.","e2":"The results are consistent with our theory.","e2t":"Sonuçlar teorimizle tutarlı."},{"w":"constant","tr":"sabit / sürekli","te":"Adjective","tt":"Sıfat","de":"Happening all the time or staying the same","dt":"Her zaman olan veya aynı kalan","e1":"I can't work with this constant noise.","e1t":"Bu sürekli gürültüyle çalışamam.","e2":"The speed of light is constant.","e2t":"Işık hızı sabittir."},{"w":"constantly","tr":"sürekli olarak","te":"Adverb","tt":"Zarf","de":"All the time or very often","dt":"Her zaman veya çok sık","e1":"He is constantly checking his phone.","e1t":"Sürekli olarak telefonunu kontrol ediyor.","e2":"The world is constantly changing.","e2t":"Dünya sürekli olarak değişiyor."},{"w":"construct","tr":"inşa etmek / kurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To build or put something together","dt":"İnşa etmek veya bir şeyi bir araya getirmek","e1":"They are constructing a new bridge.","e1t":"Yeni bir köprü inşa ediyorlar.","e2":"He constructed a model airplane.","e2t":"Bir model uçak yaptı (kurdu)."},{"w":"construction","tr":"inşaat","te":"Noun","tt":"İsim","de":"The act or result of building","dt":"İnşa etme eylemi veya sonucu","e1":"The road is under construction.","e1t":"Yol inşaat halinde.","e2":"He works in the construction industry.","e2t":"İnşaat sektöründe çalışıyor."},{"w":"consult","tr":"danışmak","te":"Verb","tt":"Fiil","de":"To seek information or advice from","dt":"...","e1":"den bilgi veya tavsiye almak","e1t":"You should consult a lawyer.","e2":"Bir avukata danışmalısın.","e2t":"Consult the dictionary for the meaning."},{"w":"consultant","tr":"danışman","te":"Noun","tt":"İsim","de":"A specialist who gives professional advice","dt":"Profesyonel tavsiye veren uzman","e1":"He works as a business consultant.","e1t":"İş danışmanı olarak çalışıyor.","e2":"The company hired a marketing consultant.","e2t":"Şirket bir pazarlama danışmanı tuttu."},{"w":"consume","tr":"tüketmek","te":"Verb","tt":"Fiil","de":"To eat, drink, or use something up","dt":"Yemek, içmek veya bir şeyi kullanıp bitirmek","e1":"This car consumes a lot of fuel.","e1t":"Bu araba çok yakıt tüketiyor.","e2":"We should consume less sugar.","e2t":"Daha az şeker tüketmeliyiz."},{"w":"consumer","tr":"tüketici","te":"Noun","tt":"İsim","de":"A person who buys goods or services","dt":"Mal veya hizmet satın alan kişi","e1":"Consumer rights are protected by law.","e1t":"Tüketici hakları yasayla korunur.","e2":"The new product is popular with consumers.","e2t":"Yeni ürün tüketiciler arasında popüler."},{"w":"contact","tr":"iletişim / temas","te":"Noun/Verb","tt":"İsim/Fiil","de":"Communication or physical touching","dt":"İletişim veya fiziksel dokunma","e1":"I lost contact with my old friends.","e1t":"Eski arkadaşlarımla iletişimimi kaybettim.","e2":"Please contact me if you need help.","e2t":"Yardıma ihtiyacın olursa lütfen benimle iletişime geç."},{"w":"contain","tr":"içermek","te":"Verb","tt":"Fiil","de":"To have something inside","dt":"İçinde bir şeye sahip olmak","e1":"This bottle contains orange juice.","e1t":"Bu şişe portakal suyu içeriyor.","e2":"The book contains ten chapters.","e2t":"Kitap on bölümden oluşuyor (içeriyor)."},{"w":"container","tr":"kap / konteyner","te":"Noun","tt":"İsim","de":"A box, bottle, or jar that holds something","dt":"Bir şeyi tutan kutu, şişe veya kavanoz","e1":"Put the food in a plastic container.","e1t":"Yiyeceği plastik bir kaba koy.","e2":"The ship is carrying 100 containers.","e2t":"Gemi 100 konteyner taşıyor."},{"w":"contemporary","tr":"çağdaş","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Modern or belonging to the same time","dt":"Modern veya aynı zamana ait olan","e1":"I like contemporary art.","e1t":"Çağdaş sanatı severim.","e2":"Shakespeare and Marlowe were contemporaries.","e2t":"Shakespeare ve Marlowe çağdaşlardı."},{"w":"content","tr":"içerik / memnun","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The things inside or happy and satisfied","dt":"İçindeki şeyler veya mutlu ve tatmin olmuş","e1":"What is the content of the letter?","e1t":"Mektubun içeriği nedir?","e2":"He is content with his life.","e2t":"Hayatından memnun."},{"w":"contest","tr":"yarışma","te":"Noun/Verb","tt":"İsim/Fiil","de":"A competition or a struggle for power","dt":"Yarışma veya güç mücadelesi","e1":"He won the singing contest.","e1t":"Şarkı yarışmasını kazandı.","e2":"They are contesting the election results.","e2t":"Seçim sonuçlarına itiraz ediyorlar (çekişiyorlar)."},{"w":"context","tr":"bağlam","te":"Noun","tt":"İsim","de":"The situation in which something happens","dt":"Bir şeyin gerçekleştiği durum","e1":"You must look at the word in context.","e1t":"Kelimeye bağlam içinde bakmalısın.","e2":"It is important to understand the historical context.","e2t":"Tarihsel bağlamı anlamak önemlidir."},{"w":"continent","tr":"kıta","te":"Noun","tt":"İsim","de":"One of the large land masses of the earth","dt":"Dünyanın büyük kara kütlelerinden biri","e1":"Asia is the largest continent.","e1t":"Asya en büyük kıtadır.","e2":"Which continent is Turkey in?","e2t":"Türkiye hangi kıtadadır?"},{"w":"continue","tr":"devam etmek","te":"Verb","tt":"Fiil","de":"To keep happening or doing something","dt":"Olmaya veya yapmaya devam etmek","e1":"Please continue reading.","e1t":"Lütfen okumaya devam et.","e2":"The rain continued all day.","e2t":"Yağmur tüm gün devam etti."},{"w":"continuous","tr":"sürekli / kesintisiz","te":"Adjective","tt":"Sıfat","de":"Happening without stopping","dt":"Durmadan gerçekleşen","e1":"There was a continuous flow of traffic.","e1t":"Kesintisiz bir trafik akışı vardı.","e2":"Learning is a continuous process.","e2t":"Öğrenme sürekli bir süreçtir."},{"w":"contract","tr":"sözleşme","te":"Noun","tt":"İsim","de":"A formal legal agreement","dt":"Resmi yasal anlaşma","e1":"I signed a two","e1t":"year contract.","e2":"İki yıllık bir sözleşme imzaladım.","e2t":"Read the contract before you sign."},{"w":"contrast","tr":"zıtlık / karşılaştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A clear difference between things","dt":"Şeyler arasındaki net fark","e1":"There is a sharp contrast between the two colors.","e1t":"İki renk arasında keskin bir zıtlık var.","e2":"Contrast his work with yours.","e2t":"Onun çalışmasını seninkiyle karşılaştır."},{"w":"contribute","tr":"katkıda bulunmak","te":"Verb","tt":"Fiil","de":"To give money or help to something","dt":"Bir şeye para veya yardım vermek","e1":"He contributed $100 to the charity.","e1t":"Hayır kurumuna 100 dolar bağışladı (katkıda bulundu).","e2":"Everyone should contribute to the discussion.","e2t":"Herkes tartışmaya katkıda bulunmalı."},{"w":"contribution","tr":"katkı","te":"Noun","tt":"İsim","de":"Something that you give or do to help","dt":"Yardım için verdiğiniz veya yaptığınız şey","e1":"Thank you for your contribution.","e1t":"Katkınız için teşekkürler.","e2":"He made a significant contribution to science.","e2t":"Bilime önemli bir katkıda bulundu."},{"w":"control","tr":"kontrol etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To order or limit something","dt":"Bir şeyi düzenlemek veya sınırlamak","e1":"He can't control his anger.","e1t":"Öfkesini kontrol edemiyor.","e2":"The police are in control of the situation.","e2t":"Polis durumun kontrolünü elinde tutuyor."},{"w":"convenient","tr":"uygun","te":"Adjective","tt":"Sıfat","de":"Useful or easy to do","dt":"Yararlı veya yapması kolay","e1":"Is it convenient for you to meet now?","e1t":"Şu an buluşmak senin için uygun mu?","e2":"The shop is in a convenient location.","e2t":"Dükkan uygun bir konumda."},{"w":"convention","tr":"gelenek / kongre","te":"Noun","tt":"İsim","de":"A traditional way of behaving or a large meeting","dt":"Geleneksel davranış biçimi veya büyük toplantı","e1":"It is a social convention to shake hands.","e1t":"El sıkışmak sosyal bir gelenektir.","e2":"He is attending a comic book convention.","e2t":"Bir çizgi roman kongresine katılıyor."},{"w":"conversation","tr":"konuşma","te":"Noun","tt":"İsim","de":"A talk between two or more people","dt":"İki veya daha fazla kişi arasındaki konuşma","e1":"I had an interesting conversation with him.","e1t":"Onunla ilginç bir konuşma yaptım.","e2":"Let's have a short conversation.","e2t":"Kısa bir sohbet edelim."},{"w":"convert","tr":"dönüştürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To change from one form or belief to another","dt":"Bir formdan veya inançtan diğerine dönüşmek","e1":"Can you convert this file to PDF?","e1t":"Bu dosyayı PDF'e dönüştürebilir misin?","e2":"They converted the old barn into a house.","e2t":"Eski ahırı bir eve dönüştürdüler."},{"w":"convince","tr":"ikna etmek","te":"Verb","tt":"Fiil","de":"To make someone believe something is true","dt":"Birini bir şeyin doğru olduğuna inandırmak","e1":"I tried to convince him to stay.","e1t":"Onu kalmaya ikna etmeye çalıştım.","e2":"She convinced me that I was wrong.","e2t":"Yanlış olduğuma beni ikna etti."},{"w":"cooker","tr":"ocak / fırın","te":"Noun","tt":"İsim","de":"A piece of equipment for cooking food","dt":"Yemek pişirmek için kullanılan ekipman","e1":"We bought a new gas cooker.","e1t":"Yeni bir gazlı ocak aldık.","e2":"The cooker is easy to clean.","e2t":"Ocağın temizlenmesi kolaydır."},{"w":"cooking","tr":"yemek pişirme","te":"Noun","tt":"İsim","de":"The activity of preparing food","dt":"Yemek hazırlama faaliyeti","e1":"My mother's cooking is the best.","e1t":"Anneminki en iyi yemektir.","e2":"I enjoy Italian cooking.","e2t":"İtalyan yemeklerini (pişirme tarzını) severim."},{"w":"cooperate","tr":"iş birliği yapmak","te":"Verb","tt":"Fiil","de":"To work together for a common purpose","dt":"Ortak bir amaç için birlikte çalışmak","e1":"We must cooperate to solve the problem.","e1t":"Sorunu çözmek için iş birliği yapmalıyız.","e2":"The two companies decided to cooperate.","e2t":"İki şirket iş birliği yapmaya karar verdi."},{"w":"cooperation","tr":"iş birliği","te":"Noun","tt":"İsim","de":"The act of working together","dt":"Birlikte çalışma eylemi","e1":"Thank you for your cooperation.","e1t":"İş birliğiniz için teşekkürler.","e2":"International cooperation is essential.","e2t":"Uluslararası iş birliği esastır."},{"w":"coordinate","tr":"koordine etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To organize different parts of an activity","dt":"Bir faaliyetin farklı parçalarını organize etmek","e1":"We need to coordinate our efforts.","e1t":"Çabalarımızı koordine etmeliyiz.","e2":"What are the coordinates of the location?","e2t":"Konumun koordinatları nedir?"},{"w":"cop","tr":"polis","te":"Noun","tt":"İsim","de":"A police officer (informal)","dt":"Polis memuru (gayriresmi)","e1":"He wants to be a cop.","e1t":"Polis olmak istiyor.","e2":"The cops arrived quickly.","e2t":"Polisler hızla geldi."},{"w":"copy","tr":"kopyalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something that is exactly like another","dt":"Başka bir şeyin aynısını yapmak","e1":"Can you copy this document?","e1t":"Bu belgeyi kopyalayabilir misin?","e2":"I need a copy of the key.","e2t":"Anahtarın bir kopyasına ihtiyacım var."},{"w":"core","tr":"çekirdek / merkez","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The central or most important part","dt":"Merkezi veya en önemli parça","e1":"The earth has a hot core.","e1t":"Dünyanın sıcak bir çekirdeği vardır.","e2":"This is the core problem.","e2t":"Temel (merkezi) sorun budur."},{"w":"corn","tr":"mısır","te":"Noun","tt":"İsim","de":"A tall plant that produces yellow grains","dt":"Sarı taneler üreten uzun bitki","e1":"I like boiled corn.","e1t":"Haşlanmış mısırı severim.","e2":"They grow corn in this field.","e2t":"Bu tarlada mısır yetiştiriyorlar."},{"w":"corner","tr":"köşe","te":"Noun","tt":"İsim","de":"The point where two lines or roads meet","dt":"İki çizginin veya yolun birleştiği nokta","e1":"There is a shop on the corner.","e1t":"Köşede bir dükkan var.","e2":"Write your name in the top corner.","e2t":"İsmini üst köşeye yaz."},{"w":"corporate","tr":"kurumsal","te":"Adjective","tt":"Sıfat","de":"Relating to a large company","dt":"Büyük bir şirketle ilgili","e1":"He works in the corporate world.","e1t":"Kurumsal dünyada çalışıyor.","e2":"The company has a corporate identity.","e2t":"Şirketin bir kurumsal kimliği var."},{"w":"corporation","tr":"kurum / şirket","te":"Noun","tt":"İsim","de":"A large company or group","dt":"Büyük şirket veya grup","e1":"He works for a multinational corporation.","e1t":"Çok uluslu bir şirkette çalışıyor.","e2":"The corporation is growing fast.","e2t":"Kurum hızla büyüyor."},{"w":"correct","tr":"doğru","te":"Adjective/Verb","tt":"Accurate or without mistakes","de":"Doğru veya hatasız","dt":"Is this the correct answer?","e1":"Bu doğru cevap mı?","e1t":"Please correct your mistakes.","e2":"Lütfen hatalarını düzelt.","e2t":""},{"w":"correctly","tr":"doğru bir şekilde","te":"Adverb","tt":"Zarf","de":"In a correct way","dt":"Doğru şekilde","e1":"Did I spell your name correctly?","e1t":"İsmini doğru heceledim mi?","e2":"He followed the instructions correctly.","e2t":"Talimatları doğru şekilde takip etti."},{"w":"cost","tr":"maliyet / tutmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The price or to have a price","dt":"Fiyat veya bir fiyata sahip olmak","e1":"What is the total cost?","e1t":"Toplam maliyet nedir?","e2":"This car costs a lot of money.","e2t":"Bu araba çok para tutuyor (maliyeti yüksek)."},{"w":"cottage","tr":"kulübe / kır evi","te":"Noun","tt":"İsim","de":"A small house in the countryside","dt":"Kırsal alandaki küçük ev","e1":"We stayed in a beautiful cottage.","e1t":"Güzel bir kır evinde kaldık.","e2":"The cottage has a small garden.","e2t":"Evin küçük bir bahçesi var."},{"w":"cotton","tr":"pamuk","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A soft white material from a plant","dt":"Bir bitkiden elde edilen yumuşak beyaz malzeme","e1":"This shirt is 100% cotton.","e1t":"Bu gömlek %100 pamuk.","e2":"Cotton clothes are good for summer.","e2t":"Pamuklu kıyafetler yaz için iyidir."},{"w":"cough","tr":"öksürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To force air out of the throat with a noise","dt":"Boğazdan gürültüyle hava çıkarmak","e1":"He has a bad cough.","e1t":"Kötü bir öksürüğü var.","e2":"Cover your mouth when you cough.","e2t":"Öksürürken ağzını kapat."},{"w":"could","tr":"","te":"ebilirdi","tt":"Modal Verb","de":"Past of 'can' or for possibility","dt":"'Can' fiilinin geçmişi veya olasılık için","e1":"I could swim when I was five.","e1t":"Beş yaşındayken yüzebiliyordum.","e2":"It could rain tonight.","e2t":"Bu gece yağmur yağabilir."},{"w":"council","tr":"konsey / meclis","te":"Noun","tt":"İsim","de":"A group of people who manage a town/org","dt":"Bir kasaba veya organizasyonu yöneten grup","e1":"He is a member of the city council.","e1t":"Şehir meclisinin bir üyesidir.","e2":"The council met to discuss the project.","e2t":"Konsey projeyi tartışmak için toplandı."},{"w":"counsel","tr":"tavsiye / danışman","te":"Noun/Verb","tt":"İsim/Fiil","de":"Advice or a lawyer","dt":"Tavsiye veya avukat","e1":"He sought counsel from a lawyer.","e1t":"Bir avukattan tavsiye (hukuki yardım) istedi.","e2":"She counseled him on his career.","e2t":"Kariyeri konusunda ona tavsiye verdi."},{"w":"count","tr":"saymak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say numbers in order","dt":"Sayıları sırayla söylemek","e1":"Can you count to ten in English?","e1t":"İngilizce on'a kadar sayabilir misin?","e2":"Every vote counts.","e2t":"Her oy sayılır."},{"w":"counter","tr":"tezgah / karşı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat surface in a shop or opposite","dt":"Dükkandaki düz yüzey veya karşı/zıt","e1":"Pay at the counter, please.","e1t":"Lütfen tezgahta (kasada) ödeyin.","e2":"He made a counter","e2t":"argument."},{"w":"countryside","tr":"kırsal","te":"Noun","tt":"İsim","de":"Land outside towns and cities","dt":"Kasaba ve şehirlerin dışındaki arazi","e1":"I love walking in the countryside.","e1t":"Kırsalda yürümeyi severim.","e2":"We live in the countryside.","e2t":"Kırsalda yaşıyoruz."},{"w":"county","tr":"ilçe / bölge","te":"Noun","tt":"İsim","de":"A division of a state or country","dt":"Bir eyalet veya ülkenin bölümü","e1":"We live in a small county in Texas.","e1t":"Texas'ta küçük bir bölgede (county) yaşıyoruz.","e2":"The county office is closed.","e2t":"Bölge ofisi kapalı."},{"w":"couple","tr":"çift","te":"Noun","tt":"İsim","de":"Two people who are married or in a relationship","dt":"Evli veya ilişkisi olan iki kişi","e1":"They are a very happy couple.","e1t":"Onlar çok mutlu bir çift.","e2":"I'll be ready in a couple of minutes.","e2t":"Birkaç (bir çift) dakika içinde hazır olurum."},{"w":"courage","tr":"cesaret","te":"Noun","tt":"İsim","de":"The ability to do something dangerous","dt":"Tehlikeli bir şeyi yapma yeteneği","e1":"He showed great courage during the fire.","e1t":"Yangın sırasında büyük cesaret gösterdi.","e2":"You need courage to start a business.","e2t":"İş kurmak için cesaret gerekir."},{"w":"course","tr":"kurs","te":"Noun","tt":"İsim","de":"A set of lessons about a particular subject","dt":"Belirli bir konu hakkındaki dersler seti","e1":"I am taking an English course.","e1t":"İngilizce kursu alıyorum.","e2":"The main course was delicious.","e2t":"Ana yemek (kurs) lezzetliydi."},{"w":"court","tr":"mahkeme / kort","te":"Noun","tt":"İsim","de":"A place where trials are held or for sports","dt":"Davaların görüldüğü yer veya spor alanı","e1":"The case is going to court.","e1t":"Dava mahkemeye gidiyor.","e2":"Let's play tennis on the court.","e2t":"Kortta tenis oynayalım."},{"w":"cousin","tr":"kuzen","te":"Noun","tt":"İsim","de":"The child of your aunt or uncle","dt":"Teyze, hala, amca veya dayınızın çocuğu","e1":"My cousin lives in Germany.","e1t":"Kuzenim Almanya'da yaşıyor.","e2":"I am visiting my cousins this weekend.","e2t":"Bu hafta sonu kuzenlerimi ziyaret ediyorum."},{"w":"cover","tr":"kaplamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put something over something else","dt":"Bir şeyin üzerine başka bir şey koymak","e1":"Snow covered the mountains.","e1t":"Kar dağları kapladı.","e2":"Look at the front cover of the book.","e2t":"Kitabın ön kapağına bak."},{"w":"cowboy","tr":"kovboy","te":"Noun","tt":"Isim","de":"A person who looks after cattle in the US","dt":"ABD'de sığırlara bakan kişi","e1":"The cowboy is riding a horse.","e1t":"Kovboy ata biniyor.","e2":"A brave cowboy.","e2t":"Cesur bir kovboy."},{"w":"crack","tr":"çatlak / çatlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin line on a surface where it is broken","dt":"Kırılan bir yüzeydeki ince çizgi","e1":"There is a crack in the window.","e1t":"Pencerede bir çatlak var.","e2":"He cracked an egg into the pan.","e2t":"Tavaya bir yumurta kırdı (çatlattı)."},{"w":"craft","tr":"zanaat / beceri","te":"Noun/Verb","tt":"İsim/Fiil","de":"An activity involving skill with hands","dt":"El becerisi gerektiren faaliyet","e1":"She is interested in arts and crafts.","e1t":"Sanat ve zanaatlarla ilgileniyor.","e2":"He is a master of his craft.","e2t":"İşinin (zanaatının) ustasıdır."},{"w":"crash","tr":"kaza / çarpmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An accident or a loud noise","dt":"Kaza veya yüksek gürültü","e1":"He was injured in a car crash.","e1t":"Bir araba kazasında yaralandı.","e2":"The plane crashed into the sea.","e2t":"Uçak denize düştü (çarptı)."},{"w":"crazy","tr":"çılgın","te":"Adjective","tt":"Sıfat","de":"Mentally ill or very foolish/excited","dt":"Zihinsel hasta veya çok aptalca/heyecanlı","e1":"Are you crazy?","e1t":"Deli misin?","e2":"He is crazy about football.","e2t":"Futbol hastası (çılgını)."},{"w":"cream","tr":"krema / krem","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The fat part of milk or a skin lotion","dt":"Sütün yağlı kısmı veya cilt losyonu","e1":"Do you want cream in your coffee?","e1t":"Kahvene krema ister misin?","e2":"I need some hand cream.","e2t":"Biraz el kremine ihtiyacım var."},{"w":"create","tr":"oluşturmak","te":"Verb","tt":"Fiil","de":"To make something new","dt":"Yeni bir şey yapmak/yaratmak","e1":"He wants to create his own website.","e1t":"Kendi web sitesini oluşturmak istiyor.","e2":"Artists create beautiful things.","e2t":"Sanatçılar güzel şeyler yaratırlar."},{"w":"creation","tr":"yaratılış / eser","te":"Noun","tt":"İsim","de":"The act of creating or something made","dt":"Yaratma eylemi veya yapılan şey","e1":"The creation of the internet changed everything.","e1t":"İnternetin icadı (oluşturulması) her şeyi değiştirdi.","e2":"This painting is his latest creation.","e2t":"Bu tablo onun son eseri."},{"w":"creative","tr":"yaratıcı","te":"Adjective","tt":"Sıfat","de":"Having good imagination and original ideas","dt":"İyi hayal gücü ve özgün fikirlere sahip olma","e1":"She is a very creative person.","e1t":"O çok yaratıcı bir insandır.","e2":"We need a creative solution.","e2t":"Yaratıcı bir çözüme ihtiyacımız var."},{"w":"creature","tr":"yaratık","te":"Noun","tt":"İsim","de":"A living being, especially an animal","dt":"Canlı varlık, özellikle hayvan","e1":"The ocean is full of strange creatures.","e1t":"Okyanus tuhaf yaratıklarla doludur.","e2":"Every living creature needs water.","e2t":"Her canlı varlığın suya ihtiyacı vardır."},{"w":"credit","tr":"kredi","te":"Noun","tt":"İsim","de":"An arrangement to pay for something later","dt":"Bir şeyin ödemesini sonra yapmak için yapılan düzenleme","e1":"Can I buy this on credit?","e1t":"Bunu krediyle alabilir miyim?","e2":"I have no credit on my phone.","e2t":"Telefonumda kontör (kredi) yok."},{"w":"crew","tr":"mürettebat","te":"Noun","tt":"İsim","de":"A group of people working together on a ship/plane","dt":"Gemi veya uçakta birlikte çalışan grup","e1":"The cabin crew is very friendly.","e1t":"Kabin memurları (mürettebatı) çok arkadaş canlısı.","e2":"The film crew is preparing the set.","e2t":"Film ekibi seti hazırlıyor."},{"w":"crime","tr":"suç","te":"Noun","tt":"İsim","de":"An action that is against the law","dt":"Yasaya aykırı eylem","e1":"Crime is a serious problem in big cities.","e1t":"Suç, büyük şehirlerde ciddi bir sorundur.","e2":"Stealing is a crime.","e2t":"Çalmak bir suçtur."},{"w":"criminal","tr":"suçlu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who commits a crime or relating to crime","dt":"Suç işleyen kişi veya suçla ilgili","e1":"The police caught the criminal.","e1t":"Polis suçluyu yakaladı.","e2":"He has a criminal record.","e2t":"Sabıka (suç) kaydı var."},{"w":"crisis","tr":"kriz","te":"Noun","tt":"İsim","de":"A time of great danger or difficulty","dt":"Büyük tehlike veya zorluk zamanı","e1":"The country is facing an economic crisis.","e1t":"Ülke ekonomik bir krizle karşı karşıya.","e2":"We must act quickly in a crisis.","e2t":"Bir kriz anında hızlı hareket etmeliyiz."},{"w":"critic","tr":"eleştirmen","te":"Noun","tt":"İsim","de":"A person whose job is to give opinions on films/books","dt":"İşi film/kitaplar hakkında görüş bildirmek olan kişi","e1":"He is a famous film critic.","e1t":"O ünlü bir film eleştirmenidir.","e2":"The critics loved the movie.","e2t":"Eleştirmenler filme bayıldı."},{"w":"critical","tr":"kritik / eleştirel","te":"Adjective","tt":"Sıfat","de":"Very important or expressing disapproval","dt":"Çok önemli veya onaylamadığını belirten","e1":"The first 24 hours are critical.","e1t":"İlk 24 saat kritiktir.","e2":"Don't be so critical of his work.","e2t":"Onun çalışmasına karşı bu kadar eleştirel olma."},{"w":"criticism","tr":"eleştiri","te":"Noun","tt":"İsim","de":"The act of expressing disapproval","dt":"Onaylamadığını belirtme eylemi","e1":"He can't handle criticism.","e1t":"Eleştiriyle başa çıkamıyor.","e2":"There was a lot of criticism of the new law.","e2t":"Yeni yasaya yönelik çok fazla eleştiri vardı."},{"w":"criticize","tr":"eleştirmek","te":"Verb","tt":"Fiil","de":"To point out the faults of someone or something","dt":"Birinin veya bir şeyin hatalarını belirtmek","e1":"Stop criticizing everyone!","e1t":"Herkesi eleştirmeyi bırak!","e2":"The report criticized the government's policy.","e2t":"Rapor hükümetin politikasını eleştirdi."},{"w":"crop","tr":"mahsul","te":"Noun/Verb","tt":"İsim/Fiil","de":"Plants grown for food","dt":"Yiyecek için yetiştirilen bitkiler","e1":"The farmers are harvesting the crops.","e1t":"Çiftçiler mahsulleri hasat ediyor.","e2":"Rice is the main crop in this region.","e2t":"Pirinç bu bölgedeki temel mahsuldür."},{"w":"cross","tr":"karşıdan karşıya geçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go from one side of something to the other","dt":"Bir şeyin bir tarafından diğerine gitmek","e1":"Be careful when you cross the street.","e1t":"Caddeyi geçerken dikkatli ol.","e2":"Don't be cross with me.","e2t":"Bana kızma (darılma)."},{"w":"crowd","tr":"kalabalık","te":"Noun","tt":"İsim","de":"A large group of people together","dt":"Bir arada bulunan büyük insan grubu","e1":"There was a huge crowd at the concert.","e1t":"Konserde devasa bir kalabalık vardı.","e2":"He tried to find his friend in the crowd.","e2t":"Kalabalığın içinde arkadaşını bulmaya çalıştı."},{"w":"crowded","tr":"kalabalık","te":"Adjective","tt":"Sıfat","de":"Full of people","dt":"İnsanlarla dolu","e1":"The bus is very crowded today.","e1t":"Otobüs bugün çok kalabalık.","e2":"I don't like crowded places.","e2t":"Kalabalık yerleri sevmem."},{"w":"crown","tr":"taç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A circular head covering for a king/queen","dt":"Kral veya kraliçe için yuvarlak başlık","e1":"The queen wore a gold crown.","e1t":"Kraliçe altın bir taç taktı.","e2":"He was crowned king at 20.","e2t":"20 yaşında kral olarak taç giydi."},{"w":"crucial","tr":"çok önemli","te":"Adjective","tt":"Sıfat","de":"Extremely important or necessary","dt":"Son derece önemli veya gerekli","e1":"Water is crucial for survival.","e1t":"Su, hayatta kalmak için çok önemlidir.","e2":"This is a crucial decision for my career.","e2t":"Bu kariyerim için çok kritik (önemli) bir karar."},{"w":"cruel","tr":"zalim","te":"Adjective","tt":"Sıfat","de":"Causing pain or suffering on purpose","dt":"Bilerek acı veya ıstıraba neden olma","e1":"Don't be cruel to animals.","e1t":"Hayvanlara karşı zalim olma.","e2":"It was a cruel joke.","e2t":"Zalimce bir şakaydı."},{"w":"cruise","tr":"gemi tatili","te":"Noun/Verb","tt":"İsim/Fiil","de":"A journey on a large ship for pleasure","dt":"Eğlence için büyük bir gemide yapılan yolculuk","e1":"We went on a Mediterranean cruise.","e1t":"Akdeniz gemi turuna çıktık.","e2":"The ship is cruising at 20 knots.","e2t":"Gemi 20 deniz mili hızla seyrediyor."},{"w":"crush","tr":"ezmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To press something very hard","dt":"Bir şeyi çok sert bastırmak","e1":"Don't crush the flowers.","e1t":"Çiçekleri ezme.","e2":"I have a crush on her.","e2t":"Ona aşığım (platonik ilgi)."},{"w":"cry","tr":"ağlamak / bağırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shed tears or shout","dt":"Gözyaşı dökmek veya bağırmak","e1":"The baby is crying for milk.","e1t":"Bebek süt için ağlıyor.","e2":"I heard a cry from the dark.","e2t":"Karanlıktan bir çığlık duydum."},{"w":"crystal","tr":"kristal","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A clear transparent mineral","dt":"Şeffaf parlak mineral","e1":"The water was clear as crystal.","e1t":"Su kristal gibi berraktı.","e2":"These glasses are made of crystal.","e2t":"Bu bardaklar kristalden yapılmıştır."},{"w":"cultural","tr":"kültürel","te":"Adjective","tt":"Sıfat","de":"Relating to the habits and traditions of a group","dt":"Bir grubun alışkanlık ve gelenekleriyle ilgili","e1":"We visited many cultural sites.","e1t":"Birçok kültürel alanı ziyaret ettik.","e2":"There are cultural differences between the countries.","e2t":"Ülkeler arasında kültürel farklar var."},{"w":"culture","tr":"kültür","te":"Noun","tt":"İsim","de":"The habits and beliefs of a group of people","dt":"Bir grup insanın alışkanlıkları ve inançları","e1":"I want to learn about different cultures.","e1t":"Farklı kültürler hakkında bilgi edinmek istiyorum.","e2":"Turkish culture is very rich.","e2t":"Türk kültürü çok zengindir."},{"w":"cupboard","tr":"dolap","te":"Noun","tt":"İsim","de":"A piece of furniture with shelves for storage","dt":"Depolama için raflı mobilya","e1":"Put the plates in the cupboard.","e1t":"Tabakları dolaba koy.","e2":"The kitchen cupboard is full.","e2t":"Mutfak dolabı dolu."},{"w":"cure","tr":"tedavi etmek / çare","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a person healthy again","dt":"Bir kişiyi tekrar sağlıklı yapmak","e1":"Doctors are trying to cure the disease.","e1t":"Doktorlar hastalığı tedavi etmeye çalışıyorlar.","e2":"There is no cure for this virus yet.","e2t":"Bu virüsün henüz bir tedavisi (çaresi) yok."},{"w":"curiosity","tr":"merak","te":"Noun","tt":"İsim","de":"A strong desire to know or learn","dt":"Bilme veya öğrenme arzusu","e1":"Children are full of curiosity.","e1t":"Çocuklar merak doludur.","e2":"Curiosity killed the cat.","e2t":"Merak insanı felakete sürükler (atasözü)."},{"w":"curious","tr":"meraklı","te":"Adjective","tt":"Sıfat","de":"Wanting to know about something","dt":"Bir şeyi bilmek isteme","e1":"I am curious about your new job.","e1t":"Yeni işini merak ediyorum.","e2":"He has a curious mind.","e2t":"Meraklı bir zihni var."},{"w":"curly","tr":"kıvırcık","te":"Adjective","tt":"Sıfat","de":"Having a lot of curls","dt":"Çok fazla bukleli/kıvrımlı olma","e1":"She has long curly hair.","e1t":"Uzun kıvırcık saçları var.","e2":"He was a cute baby with curly hair.","e2t":"Kıvırcık saçlı tatlı bir bebekti."},{"w":"currency","tr":"para birimi","te":"Noun","tt":"İsim","de":"The money that is used in a country","dt":"Bir ülkede kullanılan para","e1":"What is the currency of Japan?","e1t":"Japonya'nın para birimi nedir?","e2":"I need to change some currency.","e2t":"Biraz döviz (para birimi) bozdurmam gerekiyor."},{"w":"current","tr":"güncel / akım","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Happening now or the flow of water/electricity","dt":"Şu an olan veya su/elektrik akışı","e1":"What is your current address?","e1t":"Güncel adresiniz nedir?","e2":"Be careful, the water current is strong.","e2t":"Dikkat et, su akıntısı güçlü."},{"w":"currently","tr":"şu anda","te":"Adverb","tt":"Zarf","de":"At the present time","dt":"Mevcut zamanda","e1":"He is currently working in London.","e1t":"Şu anda Londra'da çalışıyor.","e2":"The movie is currently not available.","e2t":"Film şu anda mevcut değil."},{"w":"curry","tr":"köri","te":"Noun","tt":"İsim","de":"A spicy dish or powder","dt":"Baharatlı yemek veya toz","e1":"I like chicken curry.","e1t":"Körili tavuğu severim.","e2":"Hot curry.","e2t":"Acı köri."},{"w":"curtain","tr":"perde","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of cloth used to cover a window","dt":"Pencereyi örtmek için kullanılan kumaş","e1":"Close the curtains, please.","e1t":"Lütfen perdeleri kapat.","e2":"The curtain rose and the play began.","e2t":"Perde açıldı ve oyun başladı."},{"w":"curve","tr":"eğri / kavis","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line that bends smoothly","dt":"Pürüzsüzce bükülen çizgi","e1":"The road has a sharp curve.","e1t":"Yolun keskin bir kavisi var.","e2":"The graph shows a steady curve.","e2t":"Grafik düzenli bir eğri gösteriyor."},{"w":"custom","tr":"gelenek / gümrük","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A traditional way of doing something","dt":"Bir şeyi yapmanın geleneksel yolu","e1":"It is a local custom to give gifts.","e1t":"Hediye vermek yerel bir gelenektir.","e2":"You must go through customs at the airport.","e2t":"Havaalanında gümrükten geçmelisin."},{"w":"customer","tr":"müşteri","te":"Noun","tt":"İsim","de":"A person who buys goods or services","dt":"Mal veya hizmet satın alan kişi","e1":"The shop has many regular customers.","e1t":"Dükkanın birçok düzenli müşterisi var.","e2":"Customer service is very important.","e2t":"Müşteri hizmetleri çok önemlidir."},{"w":"cut","tr":"kesmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To open or divide with something sharp","dt":"Keskin bir şeyle açmak veya bölmek","e1":"I cut my finger with a knife.","e1t":"Parmağımı bıçakla kestim.","e2":"Please cut the cake into eight pieces.","e2t":"Lütfen keki sekiz parçaya bölün."},{"w":"cycle","tr":"döngü / bisiklet sürmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of events or to ride a bike","dt":"Olaylar dizisi veya bisiklet sürmek","e1":"The water cycle is a natural process.","e1t":"Su döngüsü doğal bir süreçtir.","e2":"He cycles to work every day.","e2t":"Her gün işe bisikletle gidiyor."},{"w":"daily","tr":"günlük","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Happening or done every day","dt":"Her gün olan veya yapılan","e1":"I read the daily newspaper.","e1t":"Günlük gazeteyi okurum.","e2":"Exercise should be part of your daily routine.","e2t":"Egzersiz günlük rutininizin bir parçası olmalı."},{"w":"damage","tr":"hasar","te":"Noun/Verb","tt":"İsim/Fiil","de":"Harm or injury that causes loss of value","dt":"Değer kaybına neden olan zarar veya yaralanma","e1":"The storm caused a lot of damage.","e1t":"Fırtına çok fazla hasara yol açtı.","e2":"Smoking damages your lungs.","e2t":"Sigara içmek akciğerlerinize zarar verir."},{"w":"dancer","tr":"dansçı","te":"Noun","tt":"İsim","de":"A person who dances","dt":"Dans eden kişi","e1":"She is a professional ballet dancer.","e1t":"O profesyonel bir bale dansçısıdır.","e2":"He is a great dancer.","e2t":"O harika bir dansçıdır."},{"w":"danger","tr":"tehlike","te":"Noun","tt":"İsim","de":"The possibility of being hurt or killed","dt":"İncinme veya ölme olasılığı","e1":"The sign warns of danger.","e1t":"Tabela tehlikeye karşı uyarıyor.","e2":"He is in great danger.","e2t":"Büyük tehlike içinde."},{"w":"dangerous","tr":"tehlikeli","te":"Adjective","tt":"Sıfat","de":"Likely to cause harm","dt":"Zarar vermesi muhtemel","e1":"It is dangerous to walk alone at night.","e1t":"Gece yalnız yürümek tehlikelidir.","e2":"Tigers are dangerous animals.","e2t":"Kaplanlar tehlikeli hayvanlardır."},{"w":"dark","tr":"karanlık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Without light","dt":"Işık olmaması","e1":"It is getting dark outside.","e1t":"Dışarısı kararıyor.","e2":"I am afraid of the dark.","e2t":"Karanlıktan korkarım."},{"w":"darkness","tr":"karanlık","te":"Noun","tt":"İsim","de":"The state of being dark","dt":"Karanlık olma durumu","e1":"The room was in total darkness.","e1t":"Oda tamamen karanlık içindeydi.","e2":"He disappeared into the darkness.","e2t":"Karanlıkta kayboldu."},{"w":"data","tr":"veri","te":"Noun","tt":"İsim","de":"Facts or information used for analysis","dt":"Analiz için kullanılan gerçekler veya bilgiler","e1":"We need more data to make a decision.","e1t":"Karar vermek için daha fazla veriye ihtiyacımız var.","e2":"All the data is stored on the computer.","e2t":"Tüm veriler bilgisayarda saklanıyor."},{"w":"date","tr":"tarih / randevu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular day or a romantic meeting","dt":"Belirli bir gün veya romantik buluşma","e1":"What is the date today?","e1t":"Bugünün tarihi ne?","e2":"He has a date tonight.","e2t":"Bu gece bir randevusu var."},{"w":"dawn","tr":"şafak","te":"Noun","tt":"İsim","de":"The first light of day","dt":"Günün ilk ışığı","e1":"We woke up at dawn.","e1t":"Şafak vaktinde uyandık.","e2":"The birds start singing at dawn.","e2t":"Kuşlar şafakta ötmeye başlar."},{"w":"daylight","tr":"gün ışığı","te":"Noun","tt":"İsim","de":"Natural light during the day","dt":"Gün boyunca doğal ışık","e1":"We should finish the work in daylight.","e1t":"İşi gün ışığında bitirmeliyiz.","e2":"There are more hours of daylight in summer.","e2t":"Yazın daha fazla gün ışığı saati vardır."},{"w":"dead","tr":"ölü","te":"Adjective","tt":"Sıfat","de":"No longer living","dt":"Artık yaşamayan","e1":"The plant is dead.","e1t":"Bitki ölmüş.","e2":"He was pronounced dead at the hospital.","e2t":"Hastanede öldüğü açıklandı."},{"w":"deadline","tr":"son teslim tarihi","te":"Noun","tt":"İsim","de":"A time by which something must be finished","dt":"Bir şeyin bitirilmesi gereken zaman","e1":"The deadline for the project is Friday.","e1t":"Projenin son teslim tarihi Cuma.","e2":"We must meet the deadline.","e2t":"Son teslim tarihine yetişmeliyiz."},{"w":"deaf","tr":"sağır","te":"Adjective","tt":"Sıfat","de":"Unable to hear","dt":"Duyamama durumu","e1":"He has been deaf since birth.","e1t":"Doğuştan beri sağır.","e2":"She uses sign language because she is deaf.","e2t":"Sağır olduğu için işaret dili kullanıyor."},{"w":"deal","tr":"anlaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"An agreement between people in business","dt":"İş dünyasındaki insanlar arasındaki anlaşma","e1":"We made a deal to sell the car.","e1t":"Arabayı satmak için bir anlaşma yaptık.","e2":"How do you deal with stress?","e2t":"Stresle nasıl başa çıkıyorsun?"},{"w":"dear","tr":"sevgili / pahalı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Loved or expensive","dt":"Sevilen veya pahalı","e1":"Dear Mehmet, how are you?","e1t":"Sevgili Mehmet, nasılsın?","e2":"Life is getting very dear (expensive).","e2t":"Hayat çok pahalılaşıyor."},{"w":"death","tr":"ölüm","te":"Noun","tt":"İsim","de":"The end of a person's life","dt":"Bir kişinin hayatının sonu","e1":"The news of his death was very sad.","e1t":"Ölüm haberi çok üzücüydü.","e2":"I am afraid of death.","e2t":"Ölümden korkarım."},{"w":"debate","tr":"tartışma","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal discussion on a particular topic","dt":"Belirli bir konu üzerinde yapılan resmi tartışma","e1":"There is a big debate about nuclear energy.","e1t":"Nükleer enerji hakkında büyük bir tartışma var.","e2":"They are debating the new law.","e2t":"Yeni yasayı tartışıyorlar."},{"w":"debt","tr":"borç","te":"Noun","tt":"İsim","de":"Money that is owed to someone","dt":"Birine borçlu olunan para","e1":"He has a lot of credit card debt.","e1t":"Çok fazla kredi kartı borcu var.","e2":"I want to pay off my debts.","e2t":"Borçlarımı ödemek istiyorum."},{"w":"decade","tr":"on yıl","te":"Noun","tt":"İsim","de":"A period of ten years","dt":"On yıllık zaman dilimi","e1":"The world has changed a lot in the last decade.","e1t":"Dünya son on yılda çok değişti.","e2":"He lived in Paris for a decade.","e2t":"On yıl boyunca Paris'te yaşadı."},{"w":"decay","tr":"çürümek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To rot or become destroyed gradually","dt":"Çürümek veya kademeli olarak yıkılmak","e1":"Sugar causes tooth decay.","e1t":"Şeker diş çürümesine neden olur.","e2":"The old building is starting to decay.","e2t":"Eski bina çürümeye (yıkılmaya) başlıyor."},{"w":"decent","tr":"dürüst / yeterli","te":"Adjective","tt":"Sıfat","de":"Good, satisfactory, or polite","dt":"İyi, tatmin edici veya nazik","e1":"He is a decent man.","e1t":"O dürüst bir adamdır.","e2":"I need a decent job.","e2t":"Düzgün (yeterli) bir işe ihtiyacım var."},{"w":"decide","tr":"karar vermek","te":"Verb","tt":"Fiil","de":"To make a choice about something","dt":"Bir şey hakkında seçim yapmak","e1":"I can't decide which shirt to wear.","e1t":"Hangi gömleği giyeceğime karar veremiyorum.","e2":"They decided to sell their house.","e2t":"Evlerini satmaya karar verdiler."},{"w":"decision","tr":"karar","te":"Noun","tt":"İsim","de":"A choice that you make after thinking","dt":"Düşündükten sonra yaptığınız seçim","e1":"It was a difficult decision.","e1t":"Zor bir karardı.","e2":"I respect your decision.","e2t":"Kararına saygı duyuyorum."},{"w":"declare","tr":"ilan etmek","te":"Verb","tt":"Fiil","de":"To state something officially and publicly","dt":"Bir şeyi resmi ve halka açık şekilde belirtmek","e1":"They declared war on each other.","e1t":"Birbirlerine savaş ilan ettiler.","e2":"You must declare your income.","e2t":"Gelirinizi beyan etmelisiniz (ilan etmelisiniz)."},{"w":"decline","tr":"reddetmek / azalmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To refuse or to become less","dt":"Reddetmek veya azalmak","e1":"He declined the invitation.","e1t":"Daveti reddetti.","e2":"There is a decline in sales.","e2t":"Satışlarda bir düşüş (azalma) var."},{"w":"decorate","tr":"süslemek","te":"Verb","tt":"Fiil","de":"To make something look better by adding things","dt":"Bir şeyleri ekleyerek bir şeyin daha iyi görünmesini sağlamak","e1":"We decorated the room for the party.","e1t":"Parti için odayı süsledik.","e2":"I want to decorate my new office.","e2t":"Yeni ofisimi dekore etmek (süslemek) istiyorum."},{"w":"decoration","tr":"dekorasyon / süs","te":"Noun","tt":"İsim","de":"Something used to make a place look better","dt":"Bir yerin daha iyi görünmesi için kullanılan şey","e1":"The Christmas decorations were beautiful.","e1t":"Noel süsleri güzeldi.","e2":"He works in interior decoration.","e2t":"İç dekorasyonda çalışıyor."},{"w":"decrease","tr":"azaltmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become or make something smaller or less","dt":"Bir şeyi küçültmek veya azaltmak","e1":"The price of gold decreased yesterday.","e1t":"Altın fiyatı dün düştü (azaldı).","e2":"We need to decrease our costs.","e2t":"Maliyetlerimizi azaltmamız gerekiyor."},{"w":"dedicate","tr":"adamak","te":"Verb","tt":"Fiil","de":"To give a lot of time or effort to something","dt":"Bir şeye çok zaman veya çaba vermek","e1":"He dedicated his life to science.","e1t":"Hayatını bilime adadı.","e2":"The author dedicated the book to his wife.","e2t":"Yazar kitabı karısına adadı."},{"w":"deep","tr":"derin","te":"Adjective","tt":"Sıfat","de":"Going a long way down from the surface","dt":"Yüzeyden aşağıya doğru uzun bir yol giden","e1":"The water is very deep here.","e1t":"Burada su çok derin.","e2":"Take a deep breath.","e2t":"Derin bir nefes al."},{"w":"deeply","tr":"derinden","te":"Adverb","tt":"Zarf","de":"Very much or at a deep level","dt":"Çok fazla veya derin bir seviyede","e1":"I am deeply sorry.","e1t":"Derinden üzgünüm.","e2":"He was deeply affected by the news.","e2t":"Haberden derinden etkilendi."},{"w":"defeat","tr":"yenmek / yenilgi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To win against someone or a failure","dt":"Birine karşı kazanmak veya başarısızlık","e1":"Our team defeated the champions.","e1t":"Takımımız şampiyonları yendi.","e2":"It was a heavy defeat.","e2t":"Ağır bir yenilgiydi."},{"w":"defence","tr":"savunma","te":"Noun","tt":"İsim","de":"Protection against attack","dt":"Saldırıya karşı koruma","e1":"The country has a strong military defence.","e1t":"Ülkenin güçlü bir askeri savunması var.","e2":"What is your defence against this charge?","e2t":"Bu suçlamaya karşı savunman nedir?"},{"w":"defend","tr":"savunmak","te":"Verb","tt":"Fiil","de":"To protect someone or something from attack","dt":"Birini veya bir şeyi saldırıdan korumak","e1":"He defended his friend.","e1t":"Arkadaşını savundu.","e2":"The army is defending the city.","e2t":"Ordu şehri savunuyor."},{"w":"defendant","tr":"davalı / sanık","te":"Noun","tt":"İsim","de":"A person accused of a crime in court","dt":"Mahkemede suçla itham edilen kişi","e1":"The defendant pleaded not guilty.","e1t":"Sanık suçsuz olduğunu savundu.","e2":"The lawyer spoke for the defendant.","e2t":"Avukat sanık adına konuştu."},{"w":"deficiency","tr":"eksiklik","te":"Noun","tt":"İsim","de":"A lack of something that is needed","dt":"İhtiyaç duyulan bir şeyin eksikliği","e1":"Vitamin deficiency can cause illness.","e1t":"Vitamin eksikliği hastalığa neden olabilir.","e2":"There is a deficiency in the system.","e2t":"Sistemde bir eksiklik var."},{"w":"define","tr":"tanımlamak","te":"Verb","tt":"Fiil","de":"To explain the exact meaning of a word","dt":"Bir kelimenin tam anlamını açıklamak","e1":"How do you define success?","e1t":"Başarıyı nasıl tanımlarsın?","e2":"Can you define this term?","e2t":"Bu terimi tanımlayabilir misin?"},{"w":"definite","tr":"kesin","te":"Adjective","tt":"Sıfat","de":"Certain or clear","dt":"Kesin veya net","e1":"We need a definite answer.","e1t":"Kesin bir cevaba ihtiyacımız var.","e2":"There is a definite improvement.","e2t":"Kesin bir iyileşme var."},{"w":"definitely","tr":"kesinlikle","te":"Adverb","tt":"Zarf","de":"Without any doubt","dt":"Hiç şüphe olmaksızın","e1":"I will definitely come to your wedding.","e1t":"Düğününe kesinlikle geleceğim.","e2":"This is definitely the best cake ever.","e2t":"Bu kesinlikle şimdiye kadarki en iyi kek."},{"w":"definition","tr":"tanım","te":"Noun","tt":"İsim","de":"The exact meaning of a word or concept","dt":"Bir kelimenin veya kavramın tam anlamı","e1":"What is the definition of 'ambition'?","e1t":"'Hırs' kelimesinin tanımı nedir?","e2":"The dictionary gives several definitions.","e2t":"Sözlük birkaç tanım veriyor."},{"w":"degree","tr":"derece","te":"Noun","tt":"İsim","de":"A unit of measurement for temperature or an angle","dt":"Sıcaklık veya açı için bir ölçü birimi","e1":"Water boils at 100 degrees.","e1t":"Su 100 derecede kaynar.","e2":"He has a master's degree in physics.","e2t":"Fizik alanında yüksek lisans derecesi (diploması) var."},{"w":"delay","tr":"gecikme","te":"Noun/Verb","tt":"İsim/Fiil","de":"To make something happen later than planned","dt":"Bir şeyin planlanandan daha geç olmasını sağlamak","e1":"There is a long delay at the airport.","e1t":"Havaalanında uzun bir gecikme var.","e2":"Don't delay your decision.","e2t":"Kararını geciktirme."},{"w":"delegate","tr":"delege / temsilci","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person chosen to represent others","dt":"Başkalarını temsil etmek için seçilen kişi","e1":"He is a delegate from Turkey.","e1t":"O Türkiye'den bir delegedir.","e2":"You should delegate some tasks.","e2t":"Bazı görevleri devretmelisin (delege etmelisin)."},{"w":"deliberate","tr":"kasti / bilerek","te":"Adjective/Verb","tt":"Done on purpose","de":"Bilerek yapılan","dt":"It was a deliberate lie.","e1":"Kasti bir yalandı.","e1t":"The committee took time to deliberate.","e2":"Komite müzakere etmek (düşünmek) için zaman ayırdı.","e2t":""},{"w":"deliberately","tr":"kasten / bilerek","te":"Adverb","tt":"Zarf","de":"On purpose","dt":"Bilerek","e1":"He deliberately broke the vase.","e1t":"Vazoyu bilerek (kasten) kırdı.","e2":"She is moving deliberately slowly.","e2t":"Bilerek yavaş hareket ediyor."},{"w":"delicate","tr":"hassas / narin","te":"Adjective","tt":"Sıfat","de":"Easy to damage or break; soft","dt":"Zarar görmesi veya kırılması kolay; yumuşak","e1":"This glass is very delicate.","e1t":"Bu bardak çok narindir.","e2":"He has a delicate health.","e2t":"Hassas bir sağlığı var."},{"w":"delicious","tr":"lezzetli","te":"Adjective","tt":"Sıfat","de":"Having a very pleasant taste","dt":"Çok hoş bir tadı olma","e1":"This cake is delicious!","e1t":"Bu kek lezzetli!","e2":"The chef prepared a delicious meal.","e2t":"Şef lezzetli bir yemek hazırladı."},{"w":"delight","tr":"zevk / sevinç","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great pleasure or to please someone","dt":"Büyük zevk veya birini memnun etmek","e1":"The kids danced with delight.","e1t":"Çocuklar sevinçle dans etti.","e2":"The news delighted everyone.","e2t":"Haberler herkesi sevindirdi."},{"w":"delighted","tr":"çok memnun","te":"Adjective","tt":"Sıfat","de":"Very happy and satisfied","dt":"Çok mutlu ve tatmin olmuş","e1":"I am delighted to meet you.","e1t":"Sizinle tanıştığıma çok memnun oldum.","e2":"She was delighted with her gift.","e2t":"Hediyesinden dolayı çok mutluydu."},{"w":"deliver","tr":"teslim etmek","te":"Verb","tt":"Fiil","de":"To take goods or letters to a person or place","dt":"Malları veya mektupları bir kişiye veya yere götürmek","e1":"The supermarket delivers on Sundays.","e1t":"Süpermarket pazar günleri teslimat yapıyor.","e2":"My package was delivered today.","e2t":"Paketim bugün teslim edildi."},{"w":"delivery","tr":"teslimat","te":"Noun","tt":"İsim","de":"The act of taking goods to a place","dt":"Malları bir yere götürme eylemi","e1":"Is there a charge for delivery?","e1t":"Teslimat için bir ücret var mı?","e2":"The delivery was late.","e2t":"Teslimat gecikti."},{"w":"demand","tr":"talep","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong request for something","dt":"Bir şey için güçlü bir istek","e1":"There is a high demand for new houses.","e1t":"Yeni evler için yüksek bir talep var.","e2":"They demand a better salary.","e2t":"Daha iyi bir maaş talep ediyorlar."},{"w":"democracy","tr":"demokrasi","te":"Noun","tt":"İsim","de":"A system of government by all the people","dt":"Tüm halk tarafından yönetilen hükümet sistemi","e1":"Freedom is essential for democracy.","e1t":"Özgürlük demokrasi için esastır.","e2":"We live in a democracy.","e2t":"Bir demokraside yaşıyoruz."},{"w":"democratic","tr":"demokratik","te":"Adjective","tt":"Sıfat","de":"Relating to or supporting democracy","dt":"Demokrasi ile ilgili veya onu destekleyen","e1":"We need a democratic election.","e1t":"Demokratik bir seçime ihtiyacımız var.","e2":"He has democratic values.","e2t":"Demokratik değerleri var."},{"w":"demonstrate","tr":"göstermek / kanıtlamak","te":"Verb","tt":"Fiil","de":"To show how something works or is true","dt":"Bir şeyin nasıl çalıştığını veya doğru olduğunu göstermek","e1":"Let me demonstrate how to use this app.","e1t":"Bu uygulamayı nasıl kullanacağınızı göstereyim.","e2":"The test results demonstrate a clear improvement.","e2t":"Test sonuçları net bir iyileşme gösteriyor."},{"w":"demonstration","tr":"gösteri / kanıtlama","te":"Noun","tt":"İsim","de":"An act of showing or a public protest","dt":"Gösterme eylemi veya halka açık protesto","e1":"There was a peaceful demonstration in the square.","e1t":"Meydanda barışçıl bir gösteri vardı.","e2":"He gave a demonstration of the new machine.","e2t":"Yeni makinenin bir tanıtımını (gösterimini) yaptı."},{"w":"denial","tr":"inkar","te":"Noun","tt":"İsim","de":"The act of saying that something is not true","dt":"Bir şeyin doğru olmadığını söyleme eylemi","e1":"He is in denial about his illness.","e1t":"Hastalığı konusunda inkar içinde.","e2":"The government issued a denial of the rumors.","e2t":"Hükümet söylentilere yönelik bir yalanlama (inkar) yayınladı."},{"w":"dense","tr":"yoğun","te":"Adjective","tt":"Sıfat","de":"Containing a lot of things or people close together","dt":"Birbirine yakın birçok şey veya insan içeren","e1":"We walked through a dense forest.","e1t":"Yoğun bir ormanın içinden geçtik.","e2":"The fog was very dense.","e2t":"Sis çok yoğundu."},{"w":"density","tr":"yoğunluk","te":"Noun","tt":"İsim","de":"The degree to which something is dense","dt":"Bir şeyin ne kadar yoğun olduğu derecesi","e1":"The population density is high in Istanbul.","e1t":"İstanbul'da nüfus yoğunluğu yüksektir.","e2":"Aluminum has a low density.","e2t":"Alüminyumun yoğunluğu düşüktür."},{"w":"dentist","tr":"diş hekimi","te":"Noun","tt":"İsim","de":"A person who takes care of teeth","dt":"Dişlerle ilgilenen kişi","e1":"I have an appointment with the dentist.","e1t":"Diş hekimiyle bir randevum var.","e2":"You should see a dentist twice a year.","e2t":"Yılda iki kez diş hekimine görünmelisin."},{"w":"deny","tr":"inkar etmek","te":"Verb","tt":"Fiil","de":"To say that something is not true","dt":"Bir şeyin doğru olmadığını söylemek","e1":"He denied stealing the money.","e1t":"Parayı çaldığını inkar etti.","e2":"You cannot deny the facts.","e2t":"Gerçekleri inkar edemezsin."},{"w":"depart","tr":"ayrılmak","te":"Verb","tt":"Fiil","de":"To leave a place, especially at the start of a journey","dt":"Bir yerden ayrılmak, özellikle bir yolculuğun başında","e1":"The train departs at 10 AM.","e1t":"Tren sabah 10'da kalkıyor (ayrılıyor).","e2":"He departed for London yesterday.","e2t":"Dün Londra'ya gitti (ayrıldı)."},{"w":"department","tr":"departman","te":"Noun","tt":"İsim","de":"A part of an organization or a large shop","dt":"Bir organizasyonun veya büyük bir mağazanın bölümü","e1":"I work in the sales department.","e1t":"Satış departmanında çalışıyorum.","e2":"Which department is the manager in?","e2t":"Müdür hangi departmanda?"},{"w":"departure","tr":"kalkış","te":"Noun","tt":"İsim","de":"The act of leaving a place","dt":"Bir yerden ayrılma eylemi","e1":"What is your flight's departure time?","e1t":"Uçuşunuzun kalkış saati nedir?","e2":"Check the departure board.","e2t":"Kalkış panosunu kontrol et."},{"w":"depend","tr":"bağlı olmak","te":"Verb","tt":"Fiil","de":"To be decided by something else","dt":"Başka bir şeye göre karar verilmek","e1":"Our trip depends on the weather.","e1t":"Gezimiz hava durumuna bağlı.","e2":"You can always depend on me.","e2t":"Bana her zaman güvenebilirsin (bağlı kalabilirsin)."},{"w":"dependence","tr":"bağımlılık","te":"Noun","tt":"İsim","de":"The state of needing someone or something","dt":"Birine veya bir şeye ihtiyaç duyma durumu","e1":"The country's dependence on oil is high.","e1t":"Ülkenin petrole olan bağımlılığı yüksektir.","e2":"He is trying to reduce his dependence on others.","e2t":"Başkalarına olan bağımlılığını azaltmaya çalışıyor."},{"w":"dependent","tr":"bağımlı","te":"Adjective","tt":"Sıfat","de":"Needing someone or something to survive","dt":"Hayatta kalmak için birine veya bir şeye ihtiyaç duyan","e1":"Children are dependent on their parents.","e1t":"Çocuklar ebeveynlerine bağımlıdır.","e2":"Success is dependent on hard work.","e2t":"Başarı sıkı çalışmaya bağlıdır."},{"w":"depict","tr":"tasvir etmek","te":"Verb","tt":"Fiil","de":"To show someone or something in a picture or story","dt":"Birini veya bir şeyi bir resimde veya hikayede göstermek","e1":"The painting depicts a beautiful sunset.","e1t":"Tablo güzel bir gün batımını tasvir ediyor.","e2":"The movie depicts the life of a teacher.","e2t":"Film bir öğretmenin hayatını anlatıyor (tasvir ediyor)."},{"w":"deposit","tr":"depozito / yatırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money paid in advance or put in a bank","dt":"Önceden ödenen para veya bankaya yatırmak","e1":"I paid a $500 deposit for the house.","e1t":"Ev için 500 dolar depozito ödedim.","e2":"He deposited the money into his account.","e2t":"Parayı hesabına yatırdı."},{"w":"depressed","tr":"depresif / üzgün","te":"Adjective","tt":"Sıfat","de":"Feeling very unhappy for a long time","dt":"Uzun süre çok mutsuz hissetme","e1":"He felt depressed after losing his job.","e1t":"İşini kaybettikten sonra depresif hissetti.","e2":"The news made me feel depressed.","e2t":"Haberler beni üzgün (depresif) hissettirdi."},{"w":"depression","tr":"depresyon","te":"Noun","tt":"İsim","de":"A mental illness or a period of low economy","dt":"Ruhsal bir hastalık veya düşük ekonomi dönemi","e1":"She is suffering from depression.","e1t":"Depresyondan muzdarip.","e2":"The Great Depression started in 1929.","e2t":"Büyük Buhran (Depresyon) 1929'da başladı."},{"w":"depth","tr":"derinlik","te":"Noun","tt":"İsim","de":"The distance from the top to the bottom","dt":"Üstten alta olan mesafe","e1":"What is the depth of the pool?","e1t":"Havuzun derinliği ne kadar?","e2":"He explained the topic in depth.","e2t":"Konuyu derinlemesine açıkladı."},{"w":"derive","tr":"türetmek / elde etmek","te":"Verb","tt":"Fiil","de":"To get something from a source","dt":"Bir şeyi bir kaynaktan elde etmek","e1":"Many English words are derived from Latin.","e1t":"Birçok İngilizce kelime Latinceden türetilmiştir.","e2":"He derives great pleasure from reading.","e2t":"Okumaktan büyük zevk alır."},{"w":"descend","tr":"inmek","te":"Verb","tt":"Fiil","de":"To go or move downwards","dt":"Aşağı gitmek veya hareket etmek","e1":"The plane began to descend.","e1t":"Uçak alçalmaya (inmeye) başladı.","e2":"He descended the stairs slowly.","e2t":"Merdivenlerden yavaşça indi."},{"w":"describe","tr":"tanımlamak / tarif etmek","te":"Verb","tt":"Fiil","de":"To say what someone or something is like","dt":"Birinin veya bir şeyin nasıl olduğunu söylemek","e1":"Can you describe the man?","e1t":"Adamı tarif edebilir misin?","e2":"Please describe your symptoms.","e2t":"Lütfen belirtilerinizi tanımlayın."},{"w":"description","tr":"açıklama","te":"Noun","tt":"İsim","de":"Something that tells you what something is like","dt":"Bir şeyin nasıl olduğunu anlatan şey","e1":"Can you give me a description of the man?","e1t":"Adamın bir tarifini (açıklamasını) verebilir misin?","e2":"Read the product description.","e2t":"Ürün açıklamasını oku."},{"w":"deserve","tr":"hak etmek","te":"Verb","tt":"Fiil","de":"To be worthy of something","dt":"Bir şeye layık olmak","e1":"You deserve to be happy.","e1t":"Mutlu olmayı hak ediyorsun.","e2":"He deserves a promotion.","e2t":"O bir terfiyi hak ediyor."},{"w":"design","tr":"tasarım","te":"Noun/Verb","tt":"İsim/Fiil","de":"A drawing or plan of something before it is made","dt":"Bir şey yapılmadan önceki çizimi veya planı","e1":"I like the design of this kitchen.","e1t":"Bu mutfağın tasarımını sevdim.","e2":"Who designed this website?","e2t":"Bu web sitesini kim tasarladı?"},{"w":"designer","tr":"tasarımcı","te":"Noun","tt":"İsim","de":"A person who plans the look of something","dt":"Bir şeyin görünümünü planlayan kişi","e1":"She is a famous fashion designer.","e1t":"O ünlü bir moda tasarımcısıdır.","e2":"I want to be a web designer.","e2t":"Web tasarımcısı olmak istiyorum."},{"w":"desire","tr":"arzu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling that you want something","dt":"Bir şeyi istemeye dair güçlü duygu","e1":"He has a strong desire to learn.","e1t":"Güçlü bir öğrenme arzusu var.","e2":"We all desire happiness.","e2t":"Hepimiz mutluluk arzu ederiz."},{"w":"desk","tr":"çalışma masası","te":"Noun","tt":"İsim","de":"A table used for working or writing","dt":"Çalışma veya yazma için kullanılan masa","e1":"Put the books on your desk.","e1t":"Kitapları masana koy.","e2":"I spend all day at my desk.","e2t":"Tüm günümü masamda geçiriyorum."},{"w":"desktop","tr":"masaüstü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The top of a desk or a type of computer","dt":"Masanın üstü veya bir bilgisayar türü","e1":"I have a desktop computer at home.","e1t":"Evde bir masaüstü bilgisayarım var.","e2":"Clear your desktop, please.","e2t":"Masaüstünü (ekranı veya masayı) temizle lütfen."},{"w":"desperate","tr":"çaresiz","te":"Adjective","tt":"Sıfat","de":"Feeling hopeless or in great need","dt":"Umutsuz hissetme veya büyük ihtiyaç içinde olma","e1":"He was desperate for a job.","e1t":"Bir iş için çaresizdi (çok ihtiyacı vardı).","e2":"It was a desperate situation.","e2t":"Çaresiz bir durumdu."},{"w":"despite","tr":"","te":"e rağmen","tt":"Preposition","de":"Edat","dt":"Without being affected by something","e1":"Bir şeyden etkilenmeksizin","e1t":"We went out despite the rain.","e2":"Yağmura rağmen dışarı çıktık.","e2t":"He succeeded despite many problems."},{"w":"destination","tr":"varış yeri","te":"Noun","tt":"İsim","de":"The place where someone is going","dt":"Birinin gittiği yer","e1":"Antalya is a popular tourist destination.","e1t":"Antalya popüler bir turistik varış noktasıdır.","e2":"We reached our destination at night.","e2t":"Varış noktamıza gece ulaştık."},{"w":"destroy","tr":"yok etmek / yıkmak","te":"Verb","tt":"Fiil","de":"To damage something so badly that it cannot be used","dt":"Bir şeye kullanılamayacak kadar kötü zarar vermek","e1":"The fire destroyed the building.","e1t":"Yangın binayı yok etti.","e2":"Don't destroy your future.","e2t":"Geleceğini mahvetme (yok etme)."},{"w":"destruction","tr":"yıkım","te":"Noun","tt":"İsim","de":"The act of destroying something","dt":"Bir şeyi yok etme eylemi","e1":"The storm caused widespread destruction.","e1t":"Fırtına yaygın bir yıkıma neden oldu.","e2":"We must prevent the destruction of forests.","e2t":"Ormanların yok edilmesini engellemeliyiz."},{"w":"detail","tr":"detay","te":"Noun","tt":"İsim","de":"A small individual part of something","dt":"Bir şeyin küçük, bireysel parçası","e1":"Please give me more details.","e1t":"Lütfen bana daha fazla detay ver.","e2":"He explained the plan in detail.","e2t":"Planı detaylı bir şekilde açıkladı."},{"w":"detailed","tr":"detaylı","te":"Adjective","tt":"Sıfat","de":"Including many small facts","dt":"Birçok küçük gerçeği içeren","e1":"He wrote a detailed report.","e1t":"Detaylı bir rapor yazdı.","e2":"I need a detailed explanation.","e2t":"Detaylı bir açıklamaya ihtiyacım var."},{"w":"detect","tr":"tespit etmek","te":"Verb","tt":"Fiil","de":"To notice or discover something","dt":"Bir şeyi fark etmek veya keşfetmek","e1":"The test can detect the virus.","e1t":"Test virüsü tespit edebilir.","e2":"He detected a strange smell.","e2t":"Garip bir koku fark etti."},{"w":"detective","tr":"dedektif","te":"Noun","tt":"İsim","de":"A person who investigates crimes","dt":"Suçları araştıran kişi","e1":"He works as a private detective.","e1t":"Özel dedektif olarak çalışıyor.","e2":"The detective found a clue.","e2t":"Dedektif bir ipucu buldu."},{"w":"determination","tr":"kararlılık","te":"Noun","tt":"İsim","de":"The quality of being firm in a decision","dt":"Bir kararda sabit olma özelliği","e1":"She has the determination to succeed.","e1t":"Başarmak için kararlılığı var.","e2":"It took a lot of determination to finish the race.","e2t":"Yarışı bitirmek çok kararlılık gerektirdi."},{"w":"determine","tr":"belirlemek / kararlaştırmak","te":"Verb","tt":"Fiil","de":"To decide or discover officially","dt":"Resmi olarak karar vermek veya keşfetmek","e1":"We need to determine the cause of the problem.","e1t":"Sorunun sebebini belirlemeliyiz.","e2":"Your attitude determines your success.","e2t":"Tutumun başarını belirler."},{"w":"determined","tr":"kararlı","te":"Adjective","tt":"Sıfat","de":"Having a strong desire to do something","dt":"Bir şeyi yapma konusunda güçlü bir arzusu olan","e1":"I am determined to learn English.","e1t":"İngilizce öğrenmeye kararlıyım.","e2":"He is a very determined person.","e2t":"O çok kararlı biridir."},{"w":"develop","tr":"geliştirmek","te":"Verb","tt":"Fiil","de":"To grow or change into something more advanced","dt":"Daha gelişmiş bir şeye doğru büyümek veya değişmek","e1":"I want to develop my English skills.","e1t":"İngilizce becerilerimi geliştirmek istiyorum.","e2":"They are developing new software.","e2t":"Yeni bir yazılım geliştiriyorlar."},{"w":"developer","tr":"geliştirici","te":"Noun","tt":"İsim","de":"A person who creates or improves something","dt":"Bir şeyi oluşturan veya geliştiren kişi","e1":"He is a software developer.","e1t":"O bir yazılım geliştiricisidir.","e2":"The real estate developer built many houses.","e2t":"Emlak geliştiricisi birçok ev inşa etti."},{"w":"development","tr":"gelişim / gelişme","te":"Noun","tt":"İsim","de":"The process of growing or changing","dt":"Büyüme veya değişme süreci","e1":"This is an important development.","e1t":"Bu önemli bir gelişme.","e2":"Child development is a complex process.","e2t":"Çocuk gelişimi karmaşık bir süreçtir."},{"w":"device","tr":"cihaz","te":"Noun","tt":"İsim","de":"An object that has been made for a purpose","dt":"Belirli bir amaç için yapılmış nesne","e1":"This device is very easy to use.","e1t":"Bu cihazın kullanımı çok kolay.","e2":"Turn off all electronic devices.","e2t":"Tüm elektronik cihazları kapatın."},{"w":"devil","tr":"şeytan","te":"Noun","tt":"İsim","de":"An evil spirit or a very bad person","dt":"Kötü bir ruh veya çok kötü bir kişi","e1":"The devil is in the details.","e1t":"Şeytan ayrıntıda gizlidir (atasözü).","e2":"He is a little devil!","e2t":"O küçük bir şeytan (yaramaz)!"},{"w":"devote","tr":"adamak","te":"Verb","tt":"Fiil","de":"To give most of your time or effort to someone/something","dt":"Zamanınızın veya çabanızın çoğunu birine/bir şeye vermek","e1":"She devoted her life to her family.","e1t":"Hayatını ailesine adadı.","e2":"He devotes a lot of time to his hobbies.","e2t":"Hobilerine çok zaman ayırıyor."},{"w":"diagram","tr":"diyagram / şema","te":"Noun","tt":"İsim","de":"A drawing that explains how something works","dt":"Bir şeyin nasıl çalıştığını açıklayan çizim","e1":"Look at the diagram on page 20.","e1t":"20. sayfadaki diyagrama bak.","e2":"He drew a diagram of the human heart.","e2t":"İnsan kalbinin bir şemasını çizdi."},{"w":"diamond","tr":"elmas","te":"Noun","tt":"İsim","de":"A very hard transparent precious stone","dt":"Çok sert şeffaf değerli taş","e1":"Diamonds are forever.","e1t":"Elmalar sonsuzdur.","e2":"She wore a diamond ring.","e2t":"Elmas bir yüzük taktı."},{"w":"diary","tr":"günlük","te":"Noun","tt":"İsim","de":"A book in which you write your daily thoughts","dt":"Günlük düşüncelerinizi yazdığınız kitap","e1":"I keep a diary every day.","e1t":"Her gün günlük tutarım.","e2":"Read the diary of Anne Frank.","e2t":"Anne Frank'ın Günlüğü'nü oku."},{"w":"dictionary","tr":"sözlük","te":"Noun","tt":"İsim","de":"A book that gives the meanings of words","dt":"Kelimelerin anlamlarını veren kitap","e1":"Look up the word in the dictionary.","e1t":"Kelimeye sözlükten bak.","e2":"I bought an English","e2t":"Turkish dictionary."},{"w":"die","tr":"ölmek","te":"Verb","tt":"Fiil","de":"To stop living","dt":"Yaşamı durmak","e1":"Flowers die without water.","e1t":"Çiçekler susuz ölür.","e2":"He died at the age of ninety.","e2t":"Doksan yaşında öldü."},{"w":"diet","tr":"diyet","te":"Noun/Verb","tt":"İsim/Fiil","de":"The food that you eat every day","dt":"Her gün yediğiniz yiyecek","e1":"A healthy diet is important.","e1t":"Sağlıklı bir diyet önemlidir.","e2":"I am on a diet to lose weight.","e2t":"Kilo vermek için diyetteyim."},{"w":"differ","tr":"farklılık göstermek","te":"Verb","tt":"Fiil","de":"To be different from something else","dt":"Başka bir şeyden farklı olmak","e1":"Our opinions differ on this matter.","e1t":"Bu konuda fikirlerimiz farklılık gösteriyor.","e2":"The two brothers differ in character.","e2t":"İki kardeş karakter olarak farklıdır."},{"w":"difference","tr":"fark","te":"Noun","tt":"İsim","de":"The way in which things are not the same","dt":"Şeylerin aynı olmama biçimi","e1":"What is the difference between these two?","e1t":"Bu ikisi arasındaki fark nedir?","e2":"It makes no difference to me.","e2t":"Benim için fark etmez."},{"w":"different","tr":"farklı","te":"Adjective","tt":"Sıfat","de":"Not the same","dt":"Aynı olmayan","e1":"I want a different color.","e1t":"Farklı bir renk istiyorum.","e2":"Every city is different.","e2t":"Her şehir farklıdır."},{"w":"differently","tr":"farklı şekilde","te":"Adverb","tt":"Zarf","de":"In a different way","dt":"Farklı bir yolla","e1":"He views the world differently.","e1t":"Dünyaya farklı bir şekilde bakıyor.","e2":"Please try to do it differently.","e2t":"Lütfen farklı şekilde yapmaya çalışın."},{"w":"difficult","tr":"zor","te":"Adjective","tt":"Sıfat","de":"Hard to do or understand","dt":"Yapması veya anlaması zor","e1":"This is a very difficult question.","e1t":"Bu çok zor bir soru.","e2":"English grammar can be difficult.","e2t":"İngilizce gramer zor olabilir."},{"w":"difficulty","tr":"zorluk","te":"Noun","tt":"İsim","de":"The state of being difficult","dt":"Zor olma durumu","e1":"He finished the task with difficulty.","e1t":"Görevi zorlukla bitirdi.","e2":"I have difficulty in understanding him.","e2t":"Onu anlamakta zorluk çekiyorum."},{"w":"dig","tr":"kazmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break up and move earth","dt":"Toprağı parçalamak ve hareket ettirmek","e1":"The dog is digging a hole.","e1t":"Köpek bir delik kazıyor.","e2":"We need to dig deep to find water.","e2t":"Su bulmak için derin kazmamız gerekiyor."},{"w":"digital","tr":"dijital","te":"Adjective","tt":"Sıfat","de":"Using computer technology","dt":"Bilgisayar teknolojisini kullanan","e1":"We are living in a digital age.","e1t":"Dijital bir çağda yaşıyoruz.","e2":"I bought a new digital camera.","e2t":"Yeni bir dijital kamera aldım."},{"w":"dignity","tr":"haysiyet / onur","te":"Noun","tt":"İsim","de":"Self","dt":"respect or a serious manner","e1":"Özsaygı veya ciddi bir tutum","e1t":"He faced the problem with dignity.","e2":"Sorunla onuruyla yüzleşti.","e2t":"Every human deserves dignity."},{"w":"dimension","tr":"boyut","te":"Noun","tt":"İsim","de":"A measurement of space (length, width, height)","dt":"Uzay ölçüsü (uzunluk, genişlik, yükseklik)","e1":"What are the dimensions of the box?","e1t":"Kutunun boyutları nedir?","e2":"Time is the fourth dimension.","e2t":"Zaman dördüncü boyuttur."},{"w":"dinosaur","tr":"dinozor","te":"Noun","tt":"İsim","de":"A type of animal that lived millions of years ago","dt":"Milyonlarca yıl önce yaşamış bir hayvan türü","e1":"Dinosaurs became extinct long ago.","e1t":"Dinozorların nesli uzun zaman önce tükendi.","e2":"He loves reading about dinosaurs.","e2t":"Dinozorlar hakkında okumayı sever."},{"w":"dip","tr":"daldırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put something briefly into a liquid","dt":"Bir şeyi kısa süreliğine bir sıvıya koymak","e1":"Dip your biscuit in the tea.","e1t":"Bisküvini çaya daldır.","e2":"The sun dipped below the horizon.","e2t":"Güneş ufkun altına indi (daldı)."},{"w":"direct","tr":"doğrudan / yönetmek","te":"Adjective/Verb","tt":"Going straight or to lead/manage","de":"Dümdüz giden veya liderlik etmek/yönetmek","dt":"Is there a direct flight to Izmir?","e1":"İzmir'e doğrudan uçuş var mı?","e1t":"He is directing a new movie.","e2":"Yeni bir film yönetiyor.","e2t":""},{"w":"direction","tr":"yön / talimat","te":"Noun","tt":"İsim","de":"The way something points or instructions","dt":"Bir şeyin gösterdiği yol veya talimatlar","e1":"Which direction are we going?","e1t":"Hangi yöne gidiyoruz?","e2":"Read the directions carefully.","e2t":"Talimatları dikkatlice oku."},{"w":"directly","tr":"doğrudan","te":"Adverb","tt":"Zarf","de":"In a direct way or immediately","dt":"Doğrudan bir yolla veya hemen","e1":"He looked directly at me.","e1t":"Doğrudan bana baktı.","e2":"I'll go there directly after work.","e2t":"İşten hemen sonra doğrudan oraya gideceğim."},{"w":"director","tr":"yönetmen","te":"Noun","tt":"İsim","de":"A person who is in charge of a film or company","dt":"Bir filmin veya şirketin sorumlusu","e1":"He is the director of the new movie.","e1t":"O, yeni filmin yönetmenidir.","e2":"She is a managing director.","e2t":"O bir genel müdürdür (yönetici)."},{"w":"dirt","tr":"kir / toprak","te":"Noun","tt":"İsim","de":"Mud, dust, or earth","dt":"Çamur, toz veya toprak","e1":"Wash the dirt off your hands.","e1t":"Ellerindeki kiri yıka.","e2":"The car was covered in dirt.","e2t":"Araba kirle kaplıydı."},{"w":"disability","tr":"engellilik","te":"Noun","tt":"İsim","de":"A physical or mental condition that limits someone","dt":"Birini sınırlayan fiziksel veya zihinsel durum","e1":"He has a learning disability.","e1t":"Öğrenme güçlüğü (engeli) var.","e2":"The building has access for people with disabilities.","e2t":"Binanın engelli insanlar için erişimi var."},{"w":"disabled","tr":"engelli","te":"Adjective","tt":"Sıfat","de":"Having a physical or mental condition that limits movements","dt":"Hareketleri kısıtlayan fiziksel veya zihinsel duruma sahip olma","e1":"The building has access for disabled people.","e1t":"Binanın engelliler için erişimi var.","e2":"He is a disabled veteran.","e2t":"O engelli bir gazidir."},{"w":"disadvantage","tr":"dezavantaj","te":"Noun","tt":"İsim","de":"Something that causes problems or a lower position","dt":"Sorunlara veya daha düşük bir konuma neden olan şey","e1":"One disadvantage of living in a city is the noise.","e1t":"Şehirde yaşamanın bir dezavantajı gürültüdür.","e2":"Being small is a disadvantage in basketball.","e2t":"Küçük olmak basketbolda bir dezavantajdır."},{"w":"disagree","tr":"katılmamak / aynı fikirde olmamak","te":"Verb","tt":"Fiil","de":"To have a different opinion","dt":"Farklı bir fikre sahip olmak","e1":"I disagree with you on this.","e1t":"Bu konuda sana katılmıyorum.","e2":"They always disagree about money.","e2t":"Para konusunda her zaman anlaşmazlığa düşerler."},{"w":"disagreement","tr":"anlaşmazlık","te":"Noun","tt":"İsim","de":"A situation where people have different opinions","dt":"İnsanların farklı fikirlere sahip olduğu durum","e1":"There was a disagreement between the two friends.","e1t":"İki arkadaş arasında bir anlaşmazlık vardı.","e2":"We reached an agreement after a long disagreement.","e2t":"Uzun bir anlaşmazlıktan sonra bir anlaşmaya vardık."},{"w":"disappear","tr":"gözden kaybolmak","te":"Verb","tt":"Fiil","de":"To go where it cannot be seen","dt":"Görülemeyeceği bir yere gitmek","e1":"The sun disappeared behind the clouds.","e1t":"Güneş bulutların arkasında kayboldu.","e2":"My keys have disappeared!","e2t":"Anahtarlarım kayboldu (gözden yitti)!"},{"w":"disappoint","tr":"hayal kırıklığına uğratmak","te":"Verb","tt":"Fiil","de":"To fail to meet someone's expectations","dt":"Birinin beklentilerini karşılayamamak","e1":"I don't want to disappoint my parents.","e1t":"Ebeveynlerimi hayal kırıklığına uğratmak istemiyorum.","e2":"The result disappointed us.","e2t":"Sonuç bizi hayal kırıklığına uğrattı."},{"w":"disappointed","tr":"hayal kırıklığına uğramış","te":"Adjective","tt":"Sıfat","de":"Feeling sad because something was not as good as expected","dt":"Bir şey beklendiği kadar iyi olmadığı için üzgün hissetme","e1":"I am disappointed with the service.","e1t":"Hizmetten dolayı hayal kırıklığına uğradım.","e2":"He looked disappointed.","e2t":"Hayal kırıklığına uğramış göründü."},{"w":"disappointing","tr":"hayal kırıklığı yaratan","te":"Adjective","tt":"Sıfat","de":"Not as good as you hoped","dt":"Umduğunuz kadar iyi olmayan","e1":"The movie was very disappointing.","e1t":"Film hayal kırıklığı yaratacak kadar kötüydü.","e2":"It was a disappointing result.","e2t":"Hayal kırıklığı yaratan bir sonuçtu."},{"w":"disappointment","tr":"hayal kırıklığı","te":"Noun","tt":"İsim","de":"The feeling of being disappointed","dt":"Hayal kırıklığına uğramışlık hissi","e1":"To my great disappointment, it rained.","e1t":"Büyük hayal kırıklığıma rağmen yağmur yağdı.","e2":"Life is full of small disappointments.","e2t":"Hayat küçük hayal kırıklıklarıyla doludur."},{"w":"disaster","tr":"felaket","te":"Noun","tt":"İsim","de":"An event that causes great damage","dt":"Büyük hasara yol açan olay","e1":"The flood was a natural disaster.","e1t":"Sel doğal bir felaketti.","e2":"The party was a complete disaster.","e2t":"Parti tam bir felaketti."},{"w":"disc / disk","tr":"disk","te":"Noun","tt":"İsim","de":"A flat thin round object","dt":"Düz ince yuvarlak nesne","e1":"I have a slipped disc in my back.","e1t":"Belimde fıtık (kaymış disk) var.","e2":"Put the compact disc in the player.","e2t":"Kompakt diski oynatıcıya koy."},{"w":"discipline","tr":"disiplin","te":"Noun/Verb","tt":"İsim/Fiil","de":"Training to follow rules or self","dt":"control","e1":"Kuralları takip etme eğitimi veya özdenetim","e1t":"Military discipline is very strict.","e2":"Askeri disiplin çok katıdır.","e2t":"You need discipline to succeed."},{"w":"discount","tr":"indirim","te":"Noun/Verb","tt":"İsim/Fiil","de":"A reduction in price","dt":"Fiyatta azalma","e1":"Can I have a discount?","e1t":"İndirim alabilir miyim?","e2":"There is a 20% discount on all items.","e2t":"Tüm ürünlerde %20 indirim var."},{"w":"discover","tr":"keşfetmek","te":"Verb","tt":"Fiil","de":"To find out something for the first time","dt":"Bir şeyi ilk kez bulmak/öğrenmek","e1":"Scientists discovered a new planet.","e1t":"Bilim insanları yeni bir gezegen keşfettiler.","e2":"I discovered a great cafe nearby.","e2t":"Yakınlarda harika bir kafe keşfettim."},{"w":"discovery","tr":"keşif","te":"Noun","tt":"İsim","de":"The act of finding something for the first time","dt":"Bir şeyi ilk kez bulma eylemi","e1":"It was a great scientific discovery.","e1t":"Büyük bir bilimsel keşifti.","e2":"The discovery of gold changed the town.","e2t":"Altın keşfi kasabayı değiştirdi."},{"w":"discuss","tr":"tartışmak / görüşmek","te":"Verb","tt":"Fiil","de":"To talk about something to reach a decision","dt":"Karara varmak için bir şey hakkında konuşmak","e1":"We need to discuss the plan.","e1t":"Planı görüşmemiz (tartışmamız) gerekiyor.","e2":"Let's discuss it over dinner.","e2t":"Akşam yemeğinde bunu tartışalım."},{"w":"discussion","tr":"tartışma","te":"Noun","tt":"İsim","de":"A talk about something with other people","dt":"Diğer insanlarla bir şey hakkında yapılan konuşma","e1":"We had a long discussion about politics.","e1t":"Politika hakkında uzun bir tartışma yaptık.","e2":"The topic is open for discussion.","e2t":"Konu tartışmaya açıktır."},{"w":"disease","tr":"hastalık","te":"Noun","tt":"İsim","de":"An illness of the body or mind","dt":"Vücudun veya zihnin rahatsızlığı","e1":"Smoking causes heart disease.","e1t":"Sigara içmek kalp hastalığına neden olur.","e2":"He is suffering from a rare disease.","e2t":"Nadir bir hastalıktan muzdarip."},{"w":"dish","tr":"yemek / tabak","te":"Noun","tt":"İsim","de":"Food prepared as part of a meal or a flat container","dt":"Bir öğünün parçası olarak hazırlanan yemek veya düz kap","e1":"Pizza is my favorite dish.","e1t":"Pizza en sevdiğim yemektir.","e2":"I washed the dishes after dinner.","e2t":"Akşam yemeğinden sonra bulaşıkları (tabakları) yıkadım."},{"w":"dishonest","tr":"dürüst olmayan","te":"Adjective","tt":"Sıfat","de":"Not honest; likely to lie or cheat","dt":"Dürüst olmayan; yalan söylemeye veya hile yapmaya meyilli","e1":"It was dishonest of him to hide the truth.","e1t":"Gerçeği gizlemesi onun dürüst olmadığını gösterir.","e2":"I don't like dishonest people.","e2t":"Dürüst olmayan insanları sevmem."},{"w":"dislike","tr":"sevmemek / hoşlanmamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To not like someone or something","dt":"Birinden veya bir şeyden hoşlanmamak","e1":"I dislike cold weather.","e1t":"Soğuk havadan hoşlanmam.","e2":"He has a strong dislike of cats.","e2t":"Kedilere karşı güçlü bir sevmemezliği (nefreti) var."},{"w":"dismiss","tr":"kovmak / reddetmek","te":"Verb","tt":"Fiil","de":"To send someone away from a job or thought","dt":"Birini işten veya düşünceden uzaklaştırmak","e1":"The manager dismissed him for being late.","e1t":"Müdür onu geç kaldığı için işten çıkardı (kovdu).","e2":"Dismiss that thought from your mind.","e2t":"O düşünceyi aklından çıkar (at)."},{"w":"disorder","tr":"bozukluk / kargaşa","te":"Noun","tt":"İsim","de":"A lack of order or a physical/mental illness","dt":"Düzen eksikliği veya fiziksel/ruhsal hastalık","e1":"He has a sleeping disorder.","e1t":"Uyku bozukluğu var.","e2":"The room was in total disorder.","e2t":"Oda tamamen kargaşa (düzensizlik) içindeydi."},{"w":"display","tr":"sergilemek / ekran","te":"Verb/Noun","tt":"Fiil/İsim","de":"To show something or a screen","dt":"Bir şeyi göstermek veya ekran","e1":"The museum is displaying old coins.","e1t":"Müze eski paraları sergiliyor.","e2":"The computer display is very clear.","e2t":"Bilgisayar ekranı çok net."},{"w":"distance","tr":"mesafe","te":"Noun","tt":"İsim","de":"The amount of space between two places","dt":"İki yer arasındaki boşluk miktarı","e1":"What is the distance to the city?","e1t":"Şehre olan mesafe nedir?","e2":"I can see the sea in the distance.","e2t":"Uzakta denizi görebiliyorum."},{"w":"distant","tr":"uzak","te":"Adjective","tt":"Sıfat","de":"Far away in space or time","dt":"Uzay veya zamanda uzakta","e1":"I can hear a distant sound.","e1t":"Uzaktan bir ses duyabiliyorum.","e2":"He is a distant relative.","e2t":"O uzak bir akrabadır."},{"w":"distinct","tr":"belirgin / farklı","te":"Adjective","tt":"Sıfat","de":"Clearly separate and different","dt":"Net bir şekilde ayrı ve farklı","e1":"There is a distinct smell of gas.","e1t":"Belirgin bir gaz kokusu var.","e2":"The two plants are distinct species.","e2t":"Bu iki bitki farklı türlerdir."},{"w":"distinction","tr":"ayrım / fark","te":"Noun","tt":"Isim","de":"A clear difference or excellence","dt":"Net bir fark veya üstünlük","e1":"There is no distinction between the two.","e1t":"İkisi arasında bir ayrım yok.","e2":"He passed the exam with distinction.","e2t":"Sınavı üstün başarıyla (ayrımla) geçti."},{"w":"distinguish","tr":"ayırt etmek","te":"Verb","tt":"Fiil","de":"To recognize the difference between things","dt":"Şeyler arasındaki farkı tanımak","e1":"It's hard to distinguish the twins.","e1t":"İkizleri ayırt etmek zor.","e2":"I can't distinguish between these two colors.","e2t":"Bu iki rengi birbirinden ayırt edemiyorum."},{"w":"distribute","tr":"dağıtmak","te":"Verb","tt":"Fiil","de":"To give something to a large group of people","dt":"Bir şeyi geniş bir gruba vermek","e1":"They are distributing food to the poor.","e1t":"Fakirlere yemek dağıtıyorlar.","e2":"The software is distributed for free.","e2t":"Yazılım ücretsiz olarak dağıtılıyor."},{"w":"distribution","tr":"dağıtım","te":"Noun","tt":"İsim","de":"The act of sharing something among a group","dt":"Bir şeyi bir grup arasında paylaşma eylemi","e1":"The distribution of leaflets started today.","e1t":"Broşürlerin dağıtımı bugün başladı.","e2":"We need a better distribution system.","e2t":"Daha iyi bir dağıtım sistemine ihtiyacımız var."},{"w":"district","tr":"bölge / ilçe","te":"Noun","tt":"İsim","de":"An area of a country or city","dt":"Bir ülkenin veya şehrin alanı/bölgesi","e1":"He lives in the business district.","e1t":"İş merkezlerinin olduğu bölgede yaşıyor.","e2":"This is a historic district of the city.","e2t":"Burası şehrin tarihi bir bölgesidir."},{"w":"disturb","tr":"rahatsız etmek","te":"Verb","tt":"Fiil","de":"To interrupt someone or make them feel anxious","dt":"Birinin sözünü kesmek veya endişeli hissettirmek","e1":"Please do not disturb.","e1t":"Lütfen rahatsız etmeyin.","e2":"The loud noise disturbed my sleep.","e2t":"Yüksek ses uykumu kaçırdı (beni rahatsız etti)."},{"w":"disturbing","tr":"rahatsız edici","te":"Adjective","tt":"Sıfat","de":"Making you feel worried or upset","dt":"Sizi endişeli veya üzgün hissettiren","e1":"It was a disturbing piece of news.","e1t":"Rahatsız edici bir haberdi.","e2":"I found the movie very disturbing.","e2t":"Filmi çok rahatsız edici buldum."},{"w":"dive","tr":"dalış yapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To jump into water or go deep under water","dt":"Suya atlamak veya suyun derinliklerine gitmek","e1":"I like to dive in the sea.","e1t":"Denizde dalış yapmayı severim.","e2":"He took a deep dive into the pool.","e2t":"Havuza derin bir dalış yaptı."},{"w":"diver","tr":"dalgıç","te":"Noun","tt":"İsim","de":"A person who dives","dt":"Dalış yapan kişi","e1":"He is a professional deep","e1t":"sea diver.","e2":"O profesyonel bir derin deniz dalgıcıdır.","e2t":"The diver found a sunken ship."},{"w":"divide","tr":"bölmek","te":"Verb","tt":"Fiil","de":"To separate into parts","dt":"Parçalara ayırmak","e1":"Divide the cake into six pieces.","e1t":"Keki altı parçaya böl.","e2":"10 divided by 2 is 5.","e2t":"10 bölü 2 beştir."},{"w":"division","tr":"bölme / bölüm","te":"Noun","tt":"İsim","de":"The act of separating or a part of an organization","dt":"Ayırma eylemi veya bir organizasyonun parçası","e1":"Can you do long division?","e1t":"Uzun bölme işlemi yapabiliyor musun?","e2":"He works in the marketing division.","e2t":"Pazarlama bölümünde çalışıyor."},{"w":"divorce","tr":"boşanma / boşanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The legal end of a marriage","dt":"Bir evliliğin yasal olarak sona ermesi","e1":"They are getting a divorce.","e1t":"Boşanıyorlar.","e2":"His parents divorced when he was young.","e2t":"Ebeveynleri o gençken boşandı."},{"w":"divorced","tr":"boşanmış","te":"Adjective","tt":"Sıfat","de":"No longer married","dt":"Artık evli olmayan","e1":"She has been divorced for two years.","e1t":"İki yıldır boşanmış durumda.","e2":"My brother is divorced.","e2t":"Erkek kardeşim boşanmış."},{"w":"document","tr":"belge","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official piece of paper with information","dt":"Bilgi içeren resmi kağıt parçası","e1":"Don't forget to sign the document.","e1t":"Belgeyi imzalamayı unutma.","e2":"You must document your expenses.","e2t":"Masraflarını belgelemelisin."},{"w":"doll","tr":"oyuncak bebek","te":"Noun","tt":"Isim","de":"A child's toy that looks like a person","dt":"İnsan gibi görünen çocuk oyuncağı","e1":"She likes playing with dolls.","e1t":"Oyuncak bebeklerle oynamayı sever.","e2":"The doll has blue eyes.","e2t":"Bebeğin mavi gözleri var."},{"w":"dollar","tr":"dolar","te":"Noun","tt":"İsim","de":"The unit of money in the US and other countries","dt":"ABD ve diğer ülkelerin para birimi","e1":"The book costs ten dollars.","e1t":"Kitap on dolar tutuyor.","e2":"Can you change these dollars into liras?","e2t":"Bu dolarları liraya çevirebilir misin?"},{"w":"dolphin","tr":"yunus","te":"Noun","tt":"İsim","de":"An intelligent sea animal","dt":"Zeki bir deniz hayvanı","e1":"We saw dolphins swimming in the sea.","e1t":"Denizde yüzen yunuslar gördük.","e2":"Dolphins are very friendly creatures.","e2t":"Yunuslar çok arkadaş canlısı yaratıklardır."},{"w":"domestic","tr":"evcil / yerli","te":"Adjective","tt":"Sıfat","de":"Relating to the home or one's own country","dt":"Evle veya kişinin kendi ülkesiyle ilgili","e1":"A cat is a domestic animal.","e1t":"Kedi evcil bir hayvandır.","e2":"This is a domestic flight.","e2t":"Bu bir iç hat (yerli) uçuşudur."},{"w":"dominant","tr":"baskın","te":"Adjective","tt":"Sıfat","de":"More important, strong, or noticeable","dt":"Daha önemli, güçlü veya fark edilir","e1":"He has a dominant personality.","e1t":"Baskın bir kişiliği var.","e2":"Red is the dominant color in the room.","e2t":"Odadaki baskın renk kırmızıdır."},{"w":"dominate","tr":"hükmetmek / domine etmek","te":"Verb","tt":"Fiil","de":"To have control or power over someone/something","dt":"Birinin/bir şeyin üzerinde kontrol veya güce sahip olmak","e1":"The company dominates the market.","e1t":"Şirket piyasaya hükmediyor.","e2":"He tries to dominate every conversation.","e2t":"Her sohbete hükmetmeye çalışıyor."},{"w":"donation","tr":"bağış","te":"Noun","tt":"İsim","de":"Money or goods given to help someone","dt":"Birine yardım etmek için verilen para veya mal","e1":"Thank you for your generous donation.","e1t":"Cömert bağışınız için teşekkür ederiz.","e2":"They collected donations for the earthquake victims.","e2t":"Depremzedeler için bağış topladılar."},{"w":"done","tr":"yapılmış / bitmiş","te":"Adjective/Verb","tt":"Finished or past participle of 'do'","de":"Bitmiş veya 'do' fiilinin üçüncü hali","dt":"Is the food done?","e1":"Yemek oldu mu (pişti mi)?","e1t":"Well done!","e2":"Aferin! (İyi iş!)","e2t":""},{"w":"donkey","tr":"eşek","te":"Noun","tt":"İsim","de":"An animal like a small horse with long ears","dt":"Uzun kulaklı, küçük ata benzeyen bir hayvan","e1":"Donkeys are known for being stubborn.","e1t":"Eşekler inatçı olmalarıyla bilinir.","e2":"The donkey carried the heavy load.","e2t":"Eşek ağır yükü taşıdı."},{"w":"doorbell","tr":"kapı zili","te":"Noun","tt":"İsim","de":"A bell on the outside of a house","dt":"Evin dışındaki zil","e1":"I heard the doorbell ring.","e1t":"Kapı zilinin çaldığını duydum.","e2":"He pressed the doorbell twice.","e2t":"Kapı ziline iki kez bastı."},{"w":"dot","tr":"nokta","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small round mark","dt":"Küçük yuvarlak işaret","e1":"Connect the dots.","e1t":"Noktaları birleştir.","e2":"There is a red dot on the screen.","e2t":"Ekranda kırmızı bir nokta var."},{"w":"double","tr":"çift","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Twice as much or having two parts","dt":"İki katı veya iki parçalı","e1":"I need a double room, please.","e1t":"Çift kişilik bir oda istiyorum lütfen.","e2":"The price has doubled this year.","e2t":"Fiyat bu yıl ikiye katlandı."},{"w":"doubt","tr":"şüphe","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of not being sure about something","dt":"Bir şeyden emin olmama duygusu","e1":"I have no doubt about his honesty.","e1t":"Onun dürüstlüğünden şüphem yok.","e2":"I doubt that he will come.","e2t":"Geleceğinden şüphe duyuyorum."},{"w":"doughnut","tr":"donat / çörek","te":"Noun","tt":"İsim","de":"A small fried cake with a hole in the middle","dt":"Ortası delik, küçük kızarmış kek","e1":"I want a chocolate doughnut.","e1t":"Çikolatalı bir donat istiyorum.","e2":"Sweet doughnut.","e2t":"Tatlı donat."},{"w":"down","tr":"aşağı","te":"Adverb/Preposition","tt":"Towards a lower position","de":"Daha düşük bir konuma doğru","dt":"Sit down, please.","e1":"Oturun lütfen.","e1t":"He fell down the stairs.","e2":"Merdivenlerden aşağı düştü.","e2t":""},{"w":"download","tr":"indirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move data from the internet to a computer","dt":"İnternetten bilgisayara veri aktarmak","e1":"You can download the file for free.","e1t":"Dosyayı ücretsiz indirebilirsiniz.","e2":"The download is almost finished.","e2t":"İndirme neredeyse bitti."},{"w":"downstairs","tr":"alt kat","te":"Adverb/Noun","tt":"On a lower floor of a building","de":"Binanın daha alt bir katında","dt":"He is waiting downstairs.","e1":"Alt katta bekliyor.","e1t":"Let's go downstairs.","e2":"Alt kata gidelim.","e2t":""},{"w":"downward","tr":"aşağıya doğru","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Moving towards a lower level","dt":"Daha düşük bir seviyeye doğru hareket etme","e1":"The stock market is on a downward trend.","e1t":"Borsa aşağı yönlü bir trendde.","e2":"She looked downward.","e2t":"Aşağıya doğru baktı."},{"w":"dozen","tr":"düzine (12 adet)","te":"Noun","tt":"İsim","de":"A group of twelve","dt":"On ikili grup","e1":"I bought a dozen eggs.","e1t":"Bir düzine yumurta aldım.","e2":"There were a dozen people in the room.","e2t":"Odada bir düzine (yaklaşık 12) kişi vardı."},{"w":"draft","tr":"taslak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A first version of a piece of writing","dt":"Yazının ilk versiyonu","e1":"This is just a rough draft.","e1t":"Bu sadece kaba bir taslak.","e2":"I need to draft a letter.","e2t":"Bir mektup taslağı hazırlamam gerekiyor."},{"w":"drag","tr":"sürüklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull something along the ground","dt":"Bir şeyi yer boyunca çekmek","e1":"Don't drag your feet!","e1t":"Ayaklarını sürükleme!","e2":"He dragged the heavy bag across the floor.","e2t":"Ağır çantayı zemin boyunca sürükledi."},{"w":"dragon","tr":"ejderha","te":"Noun","tt":"İsim","de":"A mythical large reptile with wings","dt":"Kanatlı, efsanevi büyük sürüngen","e1":"The story is about a brave knight and a dragon.","e1t":"Hikaye cesur bir şövalye ve bir ejderha hakkındadır.","e2":"Do you like movies with dragons?","e2t":"Ejderhalı filmleri sever misin?"},{"w":"drain","tr":"tahliye etmek / akıtmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make liquid flow away","dt":"Sıvının akıp gitmesini sağlamak","e1":"The water is not draining properly.","e1t":"Su düzgün tahliye olmuyor (akmıyor).","e2":"Drain the pasta.","e2t":"Makarnanın suyunu süz."},{"w":"drama","tr":"drama","te":"Noun","tt":"İsim","de":"A play for theater or an exciting event","dt":"Tiyatro oyunu veya heyecan verici olay","e1":"I like watching TV dramas.","e1t":"TV dramaları izlemeyi severim.","e2":"There was a lot of drama at school today.","e2t":"Bugün okulda çok fazla olay (drama) vardı."},{"w":"dramatic","tr":"dramatik / çarpıcı","te":"Adjective","tt":"Sıfat","de":"Sudden and surprising; exciting","dt":"Ani ve şaşırtıcı; heyecan verici","e1":"There has been a dramatic change in the weather.","e1t":"Hava durumunda dramatik (çarpıcı) bir değişiklik oldu.","e2":"It was a dramatic game.","e2t":"Heyecan dolu bir maçtı."},{"w":"dramatically","tr":"dramatik bir şekilde","te":"Adverb","tt":"Zarf","de":"In a sudden or exciting way","dt":"Ani veya heyecan verici bir yolla","e1":"Prices have risen dramatically.","e1t":"Fiyatlar dramatik bir şekilde arttı.","e2":"The situation changed dramatically.","e2t":"Durum çarpıcı bir şekilde değişti."},{"w":"drawer","tr":"çekmece","te":"Noun","tt":"İsim","de":"A sliding box in a piece of furniture","dt":"Mobilyadaki kayan kutu","e1":"The keys are in the top drawer.","e1t":"Anahtarlar üst çekmecede.","e2":"Open the drawer.","e2t":"Çekmeceyi aç."},{"w":"drawing","tr":"çizim","te":"Noun","tt":"İsim","de":"A picture made with a pencil or pen","dt":"Kalem veya kurşun kalemle yapılan resim","e1":"This is a beautiful drawing of a cat.","e1t":"Bu, güzel bir kedi çizimi.","e2":"I am taking drawing lessons.","e2t":"Çizim dersleri alıyorum."},{"w":"dream","tr":"rüya","te":"Noun/Verb","tt":"İsim/Fiil","de":"Images in your mind while you are sleeping","dt":"Uyurken zihninizdeki görüntüler","e1":"I had a strange dream last night.","e1t":"Dün gece garip bir rüya gördüm.","e2":"My dream is to become a pilot.","e2t":"Hayalim pilot olmak."},{"w":"dressed","tr":"giyinmiş","te":"Adjective","tt":"Sıfat","de":"Wearing clothes","dt":"Kıyafet giymiş olma","e1":"Are you dressed yet?","e1t":"Daha giyinmedin mi?","e2":"He was smartly dressed for the interview.","e2t":"Mülakat için şık giyinmişti."},{"w":"drill","tr":"matkap / alıştırma","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for making holes or a repetitive exercise","dt":"Delik açma aracı veya tekrarlı alıştırma","e1":"He is using a drill to fix the shelf.","e1t":"Rafı sabitlemek için matkap kullanıyor.","e2":"We had a fire drill at school.","e2t":"Okulda yangın tatbikatı (alıştırması) yaptık."},{"w":"driving","tr":"sürüş","te":"Noun","tt":"İsim","de":"The act of operating a vehicle","dt":"Araç kullanma eylemi","e1":"Driving in heavy traffic is stressful.","e1t":"Yoğun trafikte araç sürmek streslidir.","e2":"He passed his driving test.","e2t":"Sürüş (direksiyon) sınavını geçti."},{"w":"drop","tr":"düşürmek / damla","te":"Verb/Noun","tt":"Fiil/İsim","de":"To let something fall or a small bit of liquid","dt":"Bir şeyin düşmesine izin vermek veya küçük sıvı parçası","e1":"Don't drop the glass!","e1t":"Bardağı düşürme!","e2":"There were drops of rain on the window.","e2t":"Pencerede yağmur damlaları vardı."},{"w":"drought","tr":"kuraklık","te":"Noun","tt":"İsim","de":"A long period without rain","dt":"Yağmursuz geçen uzun süre","e1":"The drought destroyed the crops.","e1t":"Kuraklık mahsulleri yok etti.","e2":"We are facing a water shortage due to the drought.","e2t":"Kuraklık nedeniyle su kıtlığıyla karşı karşıyayız."},{"w":"drown","tr":"boğulmak (suda)","te":"Verb","tt":"Fiil","de":"To die under water","dt":"Su altında ölmek","e1":"He almost drowned in the river.","e1t":"Nehirde neredeyse boğuluyordu.","e2":"Thousands of animals drowned in the flood.","e2t":"Selde binlerce hayvan boğuldu."},{"w":"drug","tr":"ilaç / uyuşturucu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A medicine or an illegal substance","dt":"Tıbbi ilaç veya yasa dışı madde","e1":"The doctor prescribed a new drug.","e1t":"Doktor yeni bir ilaç yazdı.","e2":"Drug abuse is a serious problem.","e2t":"Uyuşturucu kullanımı ciddi bir sorundur."},{"w":"drum","tr":"davul","te":"Noun/Verb","tt":"İsim/Fiil","de":"A musical instrument played with sticks","dt":"Sopalarla çalınan müzik aleti","e1":"He plays the drums in a band.","e1t":"Bir grupta davul çalıyor.","e2":"I heard the sound of drums.","e2t":"Davul seslerini duydum."},{"w":"drunk","tr":"sarhoş","te":"Adjective","tt":"Sıfat","de":"Affected by drinking too much alcohol","dt":"Çok fazla alkol almaktan etkilenmiş olma","e1":"He was too drunk to drive.","e1t":"Araba süremeyecek kadar sarhoştu.","e2":"Don't get drunk tonight.","e2t":"Bu gece sarhoş olma."},{"w":"dry","tr":"kuru / kurulamak","te":"Adjective/Verb","tt":"Not wet or to remove water","de":"Islak olmayan veya suyu gidermek","dt":"The air is very dry here.","e1":"Burada hava çok kuru.","e1t":"Dry your hands with a towel.","e2":"Ellerinizi bir havluyla kurulayın.","e2t":""},{"w":"due","tr":"beklenen /","te":"den dolayı","tt":"Adjective/Preposition","de":"Expected to happen or because of","dt":"Olması beklenen veya ... nedeniyle","e1":"The train is due at 5 PM.","e1t":"Trenin saat 5'te gelmesi bekleniyor.","e2":"The flight was canceled due to bad weather.","e2t":"Uçuş kötü hava nedeniyle iptal edildi."},{"w":"dull","tr":"sıkıcı / mat","te":"Adjective","tt":"Sıfat","de":"Not interesting or not bright","dt":"İlginç olmayan veya parlak olmayan","e1":"It was a dull movie.","e1t":"Sıkıcı bir filmdi.","e2":"The knife has a dull edge.","e2t":"Bıçağın kör (keskin olmayan) bir ağzı var."},{"w":"dumb","tr":"aptal / dilsiz","te":"Adjective","tt":"Sıfat","de":"Stupid or unable to speak","dt":"Aptalca veya konuşamayan","e1":"That was a dumb mistake.","e1t":"Bu aptalca bir hataydı.","e2":"He was struck dumb with surprise.","e2t":"Şaşkınlıktan dili tutuldu (dilsiz kaldı)."},{"w":"dump","tr":"dökmek (çöp vb.)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get rid of something in a careless way","dt":"Bir şeyi dikkatsizce elden çıkarmak","e1":"Don't dump trash in the forest.","e1t":"Ormana çöp dökmeyin.","e2":"The city needs a new rubbish dump.","e2t":"Şehrin yeni bir çöp döküm alanına ihtiyacı var."},{"w":"during","tr":"sırasında","te":"Preposition","tt":"Edat","de":"Throughout the duration of","dt":"Süresi boyunca","e1":"It rained during the match.","e1t":"Maç sırasında yağmur yağdı.","e2":"I fell asleep during the movie.","e2t":"Film sırasında uyuyakaldım."},{"w":"dust","tr":"toz","te":"Noun/Verb","tt":"İsim/Fiil","de":"Dry powder made of tiny pieces of dirt","dt":"Çok küçük kir parçalarından oluşan kuru toz","e1":"The table is covered in dust.","e1t":"Masa tozla kaplı.","e2":"I need to dust the furniture.","e2t":"Mobilyaların tozunu almam gerekiyor."},{"w":"duty","tr":"görev / vergi","te":"Noun","tt":"İsim","de":"A moral or legal responsibility or a tax","dt":"Ahlaki veya yasal sorumluluk veya vergi","e1":"It is my duty to help you.","e1t":"Sana yardım etmek benim görevim.","e2":"You must pay import duty.","e2t":"İthalat vergisi ödemelisiniz."},{"w":"dvd","tr":"DVD","te":"Noun","tt":"İsim","de":"A disc used to store videos","dt":"Video depolamak için kullanılan disk","e1":"We watched a movie on DVD.","e1t":"DVD'den film izledik.","e2":"He has a large DVD collection.","e2t":"Büyük bir DVD koleksiyonu var."},{"w":"dynamic","tr":"dinamik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Full of energy and new ideas","dt":"Enerji ve yeni fikirlerle dolu","e1":"He is a dynamic leader.","e1t":"O dinamik bir liderdir.","e2":"The situation is very dynamic.","e2t":"Durum çok dinamik (değişken)."},{"w":"e","tr":"mail / email","te":"e","tt":"posta","de":"Noun/Verb","dt":"İsim/Fiil","e1":"Messages sent by computer","e1t":"Bilgisayarla gönderilen mesajlar","e2":"Send me an email.","e2t":"Bana bir e"},{"w":"eager","tr":"istekli","te":"Adjective","tt":"Sıfat","de":"Wanting to do or have something very much","dt":"Bir şeyi yapmayı veya almayı çok isteme","e1":"He is eager to learn.","e1t":"Öğrenmeye istekli.","e2":"The kids were eager for the party.","e2t":"Çocuklar parti için hevesliydi."},{"w":"eagle","tr":"kartal","te":"Noun","tt":"İsim","de":"A large bird of prey","dt":"Büyük bir yırtıcı kuş","e1":"The eagle is flying high.","e1t":"Kartal yüksekte uçuyor.","e2":"The eagle is a symbol of strength.","e2t":"Kartal gücün sembolüdür."},{"w":"earn","tr":"kazanmak","te":"Verb","tt":"Fiil","de":"To get money by working","dt":"Çalışarak para elde etmek","e1":"How much do you earn a month?","e1t":"Ayda ne kadar kazanıyorsun?","e2":"He earns a good living.","e2t":"İyi bir hayat kazanıyor (geçiniyor)."},{"w":"earnings","tr":"kazanç","te":"Noun","tt":"İsim","de":"Money obtained from working","dt":"Çalışarak elde edilen para","e1":"His monthly earnings are high.","e1t":"Aylık kazancı yüksek.","e2":"The company reported record earnings.","e2t":"Şirket rekor kazanç bildirdi."},{"w":"earring","tr":"küpe","te":"Noun","tt":"İsim","de":"A piece of jewelry worn on the lobe or edge of the ear","dt":"Kulağa takılan takı","e1":"She is wearing silver earrings.","e1t":"Gümüş küpeler takıyor.","e2":"A pair of earrings.","e2t":"Bir çift küpe."},{"w":"earthquake","tr":"deprem","te":"Noun","tt":"İsim","de":"A sudden shaking of the ground","dt":"Yerin aniden sallanması","e1":"Turkey is an earthquake zone.","e1t":"Türkiye bir deprem bölgesidir.","e2":"The earthquake lasted for 30 seconds.","e2t":"Deprem 30 saniye sürdü."},{"w":"ease","tr":"kolaylık / rahatlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Lack of difficulty or to make less painful","dt":"Zorluk olmaması veya acıyı hafifletmek","e1":"He passed the exam with ease.","e1t":"Sınavı kolaylıkla geçti.","e2":"This medicine will ease the pain.","e2t":"Bu ilaç ağrıyı hafifletecektir."},{"w":"easily","tr":"kolayca","te":"Adverb","tt":"Zarf","de":"Without any difficulty","dt":"Hiçbir zorluk olmaksızın","e1":"You can solve this problem easily.","e1t":"Bu problemi kolayca çözebilirsin.","e2":"He makes friends easily.","e2t":"Kolayca arkadaş edinir."},{"w":"eastern","tr":"doğuyla ilgili / doğuda","te":"Adjective","tt":"Sıfat","de":"Located in or relating to the east","dt":"Doğuda bulunan veya doğuyla ilgili","e1":"We visited several eastern countries.","e1t":"Birkaç doğu ülkesini ziyaret ettik.","e2":"The eastern part of the city is modern.","e2t":"Şehrin doğu kısmı moderndir."},{"w":"echo","tr":"yankı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sound that is reflected back","dt":"Geri yansıyan ses","e1":"I heard my echo in the cave.","e1t":"Mağarada yankımı duydum.","e2":"Her words echoed in my mind.","e2t":"Sözleri zihnimde yankılandı."},{"w":"economic","tr":"ekonomik","te":"Adjective","tt":"Sıfat","de":"Relating to the economy or money","dt":"Ekonomi veya para ile ilgili","e1":"The country is in an economic crisis.","e1t":"Ülke ekonomik bir krizde.","e2":"This car is very economic.","e2t":"Bu araba çok ekonomik (tasarruflu)."},{"w":"economics","tr":"ekonomi (bilim)","te":"Noun","tt":"İsim","de":"The study of money and goods","dt":"Para ve malların incelenmesi (bilimi)","e1":"He is studying economics at university.","e1t":"Üniversitede ekonomi okuyor.","e2":"Basic economics explains supply and demand.","e2t":"Temel ekonomi arz ve talebi açıklar."},{"w":"economist","tr":"ekonomist","te":"Noun","tt":"İsim","de":"A person who studies economics","dt":"Ekonomi okuyan/çalışan kişi","e1":"He works as an economist for the government.","e1t":"Hükümet için ekonomist olarak çalışıyor.","e2":"Many economists predict a rise in prices.","e2t":"Birçok ekonomist fiyatlarda artış öngörüyor."},{"w":"economy","tr":"ekonomi","te":"Noun","tt":"İsim","de":"The system of trade and industry","dt":"Ticaret ve sanayi sistemi","e1":"The world economy is growing slowly.","e1t":"Dünya ekonomisi yavaş büyüyor.","e2":"We need to improve the local economy.","e2t":"Yerel ekonomiyi iyileştirmeliyiz."},{"w":"edge","tr":"kenar","te":"Noun/Verb","tt":"İsim/Fiil","de":"The outside limit of an object","dt":"Bir nesnenin dış sınırı","e1":"Don't stand near the edge.","e1t":"Kenarın yakınında durma.","e2":"The knife has a sharp edge.","e2t":"Bıçağın keskin bir kenarı var."},{"w":"edit","tr":"düzenlemek (yazı/film)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To prepare text or film by removing mistakes","dt":"Hataları gidererek metin veya film hazırlamak","e1":"I need to edit my essay.","e1t":"Makalemi düzenlemem gerekiyor.","e2":"He is editing a new documentary.","e2t":"Yeni bir belgesel düzenliyor (montajlıyor)."},{"w":"edition","tr":"baskı / yayın","te":"Noun","tt":"İsim","de":"A particular form of a book or newspaper","dt":"Bir kitabın veya gazetenin belirli bir formu","e1":"This is the second edition of the book.","e1t":"Bu kitabın ikinci baskısıdır.","e2":"I read the Sunday edition of the newspaper.","e2t":"Gazetenin Pazar baskısını okudum."},{"w":"editor","tr":"editör","te":"Noun","tt":"İsim","de":"A person in charge of a newspaper or book","dt":"Gazete veya kitaptan sorumlu kişi","e1":"He is the editor of a local magazine.","e1t":"Yerel bir derginin editörüdür.","e2":"The editor decided to change the title.","e2t":"Editör başlığı değiştirmeye karar verdi."},{"w":"educate","tr":"eğitmek","te":"Verb","tt":"Fiil","de":"To teach someone at a school or college","dt":"Birine okulda veya kolejde ders vermek","e1":"We must educate our children.","e1t":"Çocuklarımızı eğitmeliyiz.","e2":"He was educated in Germany.","e2t":"Almanya'da eğitim gördü."},{"w":"education","tr":"eğitim","te":"Noun","tt":"İsim","de":"The process of learning or teaching","dt":"Öğrenme veya öğretme süreci","e1":"Education is important for a good job.","e1t":"İyi bir iş için eğitim önemlidir.","e2":"She wants to continue her higher education.","e2t":"Yüksek eğitimine devam etmek istiyor."},{"w":"educational","tr":"eğitici","te":"Adjective","tt":"Sıfat","de":"Providing education or information","dt":"Eğitim veya bilgi sağlayan","e1":"This is an educational program for kids.","e1t":"Bu çocuklar için eğitici bir programdır.","e2":"We visited an educational center.","e2t":"Eğitici bir merkezi ziyaret ettik."},{"w":"effect","tr":"etki","te":"Noun","tt":"İsim","de":"A change that is caused by something","dt":"Bir şeyin neden olduğu değişim","e1":"The medicine had a good effect on me.","e1t":"İlacın üzerimde iyi bir etkisi oldu.","e2":"What are the effects of global warming?","e2t":"Küresel ısınmanın etkileri nelerdir?"},{"w":"effective","tr":"etkili","te":"Adjective","tt":"Sıfat","de":"Successful in producing a result","dt":"Bir sonuç üretmede başarılı olan","e1":"This is an effective way to learn English.","e1t":"Bu İngilizce öğrenmek için etkili bir yoldur.","e2":"The medicine is very effective.","e2t":"İlaç çok etkilidir."},{"w":"effectively","tr":"etkili bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that produces a desired result","dt":"Arzulanan sonucu veren bir yolla","e1":"You need to manage your time effectively.","e1t":"Zamanınızı etkili bir şekilde yönetmelisiniz.","e2":"The problem was effectively solved.","e2t":"Sorun etkili bir şekilde çözüldü."},{"w":"efficiency","tr":"verimlilik","te":"Noun","tt":"İsim","de":"The quality of doing something without wasting time/money","dt":"Zaman/para harcamadan bir şeyi yapma kalitesi","e1":"We need to improve the efficiency of the engine.","e1t":"Motorun verimliliğini artırmamız gerekiyor.","e2":"Energy efficiency is important for the environment.","e2t":"Enerji verimliliği çevre için önemlidir."},{"w":"efficient","tr":"verimli","te":"Adjective","tt":"Sıfat","de":"Working well without wasting time or energy","dt":"Zaman veya enerji harcamadan iyi çalışma","e1":"We need an efficient way to work.","e1t":"Çalışmak için verimli bir yola ihtiyacımız var.","e2":"This car is very fuel","e2t":"efficient."},{"w":"effort","tr":"çaba","te":"Noun","tt":"İsim","de":"The physical or mental energy needed","dt":"Gereken fiziksel veya zihinsel enerji","e1":"It takes a lot of effort to learn a language.","e1t":"Bir dil öğrenmek çok çaba gerektirir.","e2":"Please make an effort to be on time.","e2t":"Lütfen vaktinde gelmek için çaba göster."},{"w":"eight","tr":"sekiz","te":"Number","tt":"Sayı","de":"The number 8","dt":"8 sayısı","e1":"I have eight apples.","e1t":"Sekiz elmam var.","e2":"The meeting starts at eight o'clock.","e2t":"Toplantı saat sekizde başlıyor."},{"w":"eighteen","tr":"on sekiz","te":"Number","tt":"Sayı","de":"The number 18","dt":"18 sayısı","e1":"He is eighteen years old.","e1t":"O on sekiz yaşında.","e2":"There are eighteen students in the class.","e2t":"Sınıfta on sekiz öğrenci var."},{"w":"eighty","tr":"seksen","te":"Number","tt":"Sayı","de":"The number 80","dt":"80 sayısı","e1":"My grandfather is eighty years old.","e1t":"Büyükbabam seksen yaşında.","e2":"The book has eighty pages.","e2t":"Kitabın seksen sayfası var."},{"w":"either","tr":"herhangi biri","te":"Determiner/Adverb","tt":"One or the other of two","de":"İki şeyden biri","dt":"You can choose either the red one or the blue one.","e1":"Ya kırmızıyı ya da maviyi seçebilirsin.","e1t":"I don't like either of them.","e2":"İkisini de sevmiyorum.","e2t":""},{"w":"elbow","tr":"dirsek","te":"Noun","tt":"İsim","de":"The joint in the middle of the arm","dt":"Kolun ortasındaki eklem","e1":"He rested his elbows on the table.","e1t":"Dirseklerini masaya dayadı.","e2":"I hit my elbow against the door.","e2t":"Dirseğimi kapıya çarptım."},{"w":"elderly","tr":"yaşlı","te":"Adjective","tt":"Sıfat","de":"A polite word for old","dt":"Yaşlı kelimesinin nazik hali","e1":"We should respect elderly people.","e1t":"Yaşlı insanlara saygı duymalıyız.","e2":"My elderly neighbor needs help.","e2t":"Yaşlı komşumun yardıma ihtiyacı var."},{"w":"elect","tr":"seçmek (oyla)","te":"Verb","tt":"Fiil","de":"To choose someone by voting","dt":"Birini oylama ile seçmek","e1":"They elected him as president.","e1t":"Onu başkan olarak seçtiler.","e2":"We need to elect a new leader.","e2t":"Yeni bir lider seçmemiz gerekiyor."},{"w":"election","tr":"seçim","te":"Noun","tt":"İsim","de":"The process of voting to choose a leader","dt":"Bir lider seçmek için yapılan oylama süreci","e1":"The presidential election is next month.","e1t":"Başkanlık seçimi gelecek ay.","e2":"Who won the election?","e2t":"Seçimi kim kazandı?"},{"w":"electric","tr":"elektrikli","te":"Adjective","tt":"Sıfat","de":"Using or producing electricity","dt":"Elektrik kullanan veya üreten","e1":"I have an electric guitar.","e1t":"Elektrikli bir gitarım var.","e2":"He drives an electric car.","e2t":"Elektrikli bir araba sürüyor."},{"w":"electrical","tr":"elektrikle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to electricity","dt":"Elektrikle ilgili olan","e1":"There is an electrical fault in the system.","e1t":"Sistemde elektriksel bir arıza var.","e2":"He is an electrical engineer.","e2t":"O bir elektrik mühendisidir."},{"w":"electricity","tr":"elektrik","te":"Noun","tt":"İsim","de":"A form of energy used for light and heat","dt":"Işık ve ısı için kullanılan bir enerji türü","e1":"Turn off the lights to save electricity.","e1t":"Elektrikten tasarruf etmek için ışıkları kapat.","e2":"The bill for electricity is very high.","e2t":"Elektrik faturası çok yüksek."},{"w":"electronic","tr":"elektronik","te":"Adjective","tt":"Sıfat","de":"Relating to devices with microchips","dt":"Mikroçipli cihazlarla ilgili","e1":"Turn off all electronic devices on the plane.","e1t":"Uçakta tüm elektronik cihazları kapatın.","e2":"I love electronic music.","e2t":"Elektronik müziği severim."},{"w":"electronics","tr":"elektronik (bilim/sektör)","te":"Noun","tt":"İsim","de":"The study or industry of electronic devices","dt":"Elektronik cihazlar bilimi veya endüstrisi","e1":"He is studying electronics.","e1t":"Elektronik okuyor.","e2":"The electronics industry is growing.","e2t":"Elektronik sektörü büyüyor."},{"w":"elegant","tr":"zarif / şık","te":"Adjective","tt":"Sıfat","de":"Graceful and stylish in appearance","dt":"Görünüşte nazik ve şık","e1":"She wore an elegant black dress.","e1t":"Zarif siyah bir elbise giydi.","e2":"The hotel has an elegant lobby.","e2t":"Otelin şık bir lobisi var."},{"w":"element","tr":"unsur","te":"Noun","tt":"İsim","de":"A part of something larger","dt":"Daha büyük bir şeyin parçası","e1":"Customer service is a key element of our business.","e1t":"Müşteri hizmetleri işimizin kilit bir unsurudur.","e2":"Water is made of two elements.","e2t":"Su iki elementten oluşur."},{"w":"elementary","tr":"temel / başlangıç","te":"Adjective","tt":"Sıfat","de":"Basic or relating to the first stages","dt":"Temel veya ilk aşamalarla ilgili","e1":"I am at an elementary level in English.","e1t":"İngilizcede başlangıç (temel) seviyesindeyim.","e2":"He goes to elementary school.","e2t":"İlkokula (temel okul) gidiyor."},{"w":"elephant","tr":"fil","te":"Noun","tt":"İsim","de":"A very large animal with a long trunk","dt":"Uzun hortumlu, çok büyük hayvan","e1":"Elephants have great memories.","e1t":"Fillerin harika hafızaları vardır.","e2":"We saw an elephant in the safari.","e2t":"Safaride bir fil gördük."},{"w":"elevator","tr":"asansör","te":"Noun","tt":"İsim","de":"A machine that carries people between floors","dt":"İnsanları katlar arasında taşıyan makine","e1":"Let's take the elevator to the 10th floor.","e1t":"10. kata asansörle çıkalım.","e2":"The elevator is out of order.","e2t":"Asansör bozuk."},{"w":"eleven","tr":"on bir","te":"Number","tt":"Sayı","de":"The number 11","dt":"11 sayısı","e1":"There are eleven players in a football team.","e1t":"Bir futbol takımında on bir oyuncu vardır.","e2":"I'll be home at eleven.","e2t":"On birde evde olacağım."},{"w":"eliminate","tr":"elemek / yok etmek","te":"Verb","tt":"Fiil","de":"To remove or get rid of something","dt":"Bir şeyi çıkarmak veya ondan kurtulmak","e1":"We need to eliminate the errors.","e1t":"Hataları elememiz (yok etmemiz) gerekiyor.","e2":"He was eliminated from the competition.","e2t":"Yarışmadan elendi."},{"w":"else","tr":"başka","te":"Adverb","tt":"Zarf","de":"In addition to or instead of","dt":"Ek olarak veya yerine","e1":"What else do you need?","e1t":"Başka neye ihtiyacın var?","e2":"Is anyone else coming?","e2t":"Başka biri geliyor mu?"},{"w":"elsewhere","tr":"başka yerde","te":"Adverb","tt":"Zarf","de":"In or to another place","dt":"Başka bir yerde veya yere","e1":"If you don't like it here, go elsewhere.","e1t":"Burayı sevmiyorsan başka yere git.","e2":"The solution must be found elsewhere.","e2t":"Çözüm başka bir yerde bulunmalı."},{"w":"embarrassed","tr":"utanmış","te":"Adjective","tt":"Sıfat","de":"Feeling ashamed or shy","dt":"Utanmış veya çekingen hissetme","e1":"I felt embarrassed when I fell down.","e1t":"Yere düştüğümde utanmış hissettim.","e2":"He was too embarrassed to speak.","e2t":"Konuşamayacak kadar utanmıştı."},{"w":"embarrassing","tr":"utanç verici","te":"Adjective","tt":"Sıfat","de":"Making you feel ashamed or shy","dt":"Sizi utanmış veya çekingen hissettiren","e1":"It was an embarrassing mistake.","e1t":"Utanç verici bir hataydı.","e2":"I had an embarrassing moment yesterday.","e2t":"Dün utanç verici bir an yaşadım."},{"w":"emergency","tr":"acil durum","te":"Noun","tt":"İsim","de":"A serious and sudden situation needing help","dt":"Yardım gerektiren ciddi ve ani durum","e1":"Call 112 in case of emergency.","e1t":"Acil durumda 112'yi arayın.","e2":"This is an emergency!","e2t":"Bu bir acil durum!"},{"w":"emotion","tr":"duygu","te":"Noun","tt":"İsim","de":"A strong feeling such as love or fear","dt":"Sevgi veya korku gibi güçlü bir duygu","e1":"Love is a very powerful emotion.","e1t":"Sevgi çok güçlü bir duygudur.","e2":"He showed no emotion during the talk.","e2t":"Konuşma sırasında hiçbir duygu göstermedi."},{"w":"emotional","tr":"duygusal","te":"Adjective","tt":"Sıfat","de":"Having or showing strong feelings","dt":"Güçlü duygulara sahip olma veya gösterme","e1":"It was a very emotional movie.","e1t":"Çok duygusal bir filmdi.","e2":"She is an emotional person.","e2t":"O duygusal bir insandır."},{"w":"emphasis","tr":"vurgu","te":"Noun","tt":"İsim","de":"Special importance or value given to something","dt":"Bir şeye verilen özel önem veya değer","e1":"The school puts emphasis on sports.","e1t":"Okul sporun üzerine vurgu yapıyor (önem veriyor).","e2":"There is an emphasis on quality.","e2t":"Kalite üzerine bir vurgu var."},{"w":"emphasize","tr":"vurgulamak","te":"Verb","tt":"Fiil","de":"To show that something is very important","dt":"Bir şeyin çok önemli olduğunu göstermek","e1":"He emphasized the importance of safety.","e1t":"Güvenliğin önemini vurguladı.","e2":"I want to emphasize this point.","e2t":"Bu noktayı vurgulamak istiyorum."},{"w":"empire","tr":"imparatorluk","te":"Noun","tt":"İsim","de":"A group of countries ruled by one person","dt":"Bir kişi tarafından yönetilen ülkeler grubu","e1":"The Ottoman Empire lasted for centuries.","e1t":"Osmanlı İmparatorluk yüzyıllarca sürdü.","e2":"He is building a business empire.","e2t":"Bir iş imparatorluğu kuruyor."},{"w":"employ","tr":"işe almak","te":"Verb","tt":"Fiil","de":"To pay someone to work for you","dt":"Birine çalışması için ödeme yapmak","e1":"The factory employs 200 people.","e1t":"Fabrika 200 kişiyi işe alıyor (çalıştırıyor).","e2":"They want to employ more staff.","e2t":"Daha fazla personel işe almak istiyorlar."},{"w":"employee","tr":"çalışan","te":"Noun","tt":"İsim","de":"A person who is paid to work for someone","dt":"Birisi için çalışması karşılığında ödeme alan kişi","e1":"The company has 50 employees.","e1t":"Şirketin 50 çalışanı var.","e2":"Every employee must wear a badge.","e2t":"Her çalışan bir yaka kartı takmalıdır."},{"w":"employer","tr":"işveren","te":"Noun","tt":"İsim","de":"A person or company that pays people to work","dt":"İnsanlara çalışması için ödeme yapan kişi veya şirket","e1":"My employer is very fair.","e1t":"İşverenim çok adildir.","e2":"He is looking for a new employer.","e2t":"Yeni bir işveren arıyor."},{"w":"employment","tr":"istihdam / iş","te":"Noun","tt":"İsim","de":"The state of having a paid job","dt":"Ücretli bir işe sahip olma durumu","e1":"Full employment is a goal of the government.","e1t":"Tam istihdam hükümetin bir hedefidir.","e2":"He is looking for permanent employment.","e2t":"Kalıcı bir iş arıyor."},{"w":"empty","tr":"boş / boşaltmak","te":"Adjective/Verb","tt":"Having nothing inside or to remove content","de":"İçinde hiçbir şey olmaması veya içeriği boşaltmak","dt":"The bottle is empty.","e1":"Şişe boş.","e1t":"Empty your pockets, please.","e2":"Lütfen ceplerini boşalt.","e2t":""},{"w":"enable","tr":"olanak tanımak","te":"Verb","tt":"Fiil","de":"To make it possible for someone to do something","dt":"Birinin bir şeyi yapmasını mümkün kılmak","e1":"Technology enables us to work from home.","e1t":"Teknoloji evden çalışmamıza olanak tanıyor.","e2":"This key enables access to the room.","e2t":"Bu anahtar odaya erişim sağlıyor."},{"w":"encounter","tr":"karşılaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To experience or meet something unexpectedly","dt":"Bir şeyi beklenmedik şekilde deneyimlemek veya biriyle buluşmak","e1":"We encountered many problems during the trip.","e1t":"Yolculuk sırasında birçok sorunla karşılaştık.","e2":"It was a brief encounter.","e2t":"Kısa bir karşılaşmaydı."},{"w":"encourage","tr":"cesaretlendirmek","te":"Verb","tt":"Fiil","de":"To give someone confidence or hope","dt":"Birine güven veya umut vermek","e1":"My teacher encouraged me to study harder.","e1t":"Öğretmenim beni daha sıkı çalışmam için cesaretlendirdi.","e2":"We should encourage children to read.","e2t":"Çocukları okumaya teşvik etmeliyiz."},{"w":"encouragement","tr":"teşvik / yüreklendirme","te":"Noun","tt":"İsim","de":"Words or actions that give hope","dt":"Umut veren sözler veya eylemler","e1":"Thank you for your encouragement.","e1t":"Teşvikiniz için teşekkürler.","e2":"He needs a bit of encouragement.","e2t":"Biraz yüreklendirilmeye ihtiyacı var."},{"w":"end","tr":"son / bitirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The final part or to finish","dt":"Son parça veya bitirmek","e1":"This is the end of the story.","e1t":"Bu hikayenin sonu.","e2":"The movie ends at 10 PM.","e2t":"Film saat 10'da bitiyor."},{"w":"ending","tr":"son (hikaye/film vb.)","te":"Noun","tt":"İsim","de":"The last part of a story or film","dt":"Bir hikaye veya filmin son kısmı","e1":"The movie has a happy ending.","e1t":"Filmin mutlu bir sonu var.","e2":"I didn't like the ending of the book.","e2t":"Kitabın sonunu sevmedim."},{"w":"endless","tr":"sonsuz","te":"Adjective","tt":"Sıfat","de":"Never finishing; continuing forever","dt":"Hiç bitmeyen; sonsuza dek süren","e1":"We had an endless discussion.","e1t":"Sonsuz bir tartışma yaptık.","e2":"The possibilities are endless.","e2t":"Olasılıklar sonsuzdur."},{"w":"endure","tr":"katlanmak / dayanmak","te":"Verb","tt":"Fiil","de":"To suffer something difficult or painful","dt":"Zor veya acı verici bir şeye katlanmak","e1":"He had to endure a lot of pain.","e1t":"Çok fazla acıya katlanmak zorunda kaldı.","e2":"These traditions endure today.","e2t":"Bu gelenekler bugün de sürüyor (dayanıyor)."},{"w":"enemy","tr":"düşman","te":"Noun","tt":"İsim","de":"A person who hates you or wants to hurt you","dt":"Sizden nefret eden veya size zarar vermek isteyen kişi","e1":"He is my worst enemy.","e1t":"O benim en kötü düşmanım.","e2":"They are fighting a common enemy.","e2t":"Ortak bir düşmana karşı savaşıyorlar."},{"w":"energy","tr":"enerji","te":"Noun","tt":"İsim","de":"Power derived from physical or chemical resources","dt":"Fiziksel veya kimyasal kaynaklardan elde edilen güç","e1":"I don't have enough energy to go out.","e1t":"Dışarı çıkacak kadar enerjim yok.","e2":"Solar energy is good for the environment.","e2t":"Güneş enerjisi çevre için iyidir."},{"w":"engage","tr":"meşgul olmak / dahil etmek","te":"Verb","tt":"Fiil","de":"To attract someone's interest or to participate","dt":"Birinin ilgisini çekmek veya katılmak","e1":"It's difficult to engage students in this topic.","e1t":"Öğrencileri bu konuya dahil etmek zor.","e2":"We need to engage with our customers.","e2t":"Müşterilerimizle etkileşime geçmeliyiz (bağ kurmalıyız)."},{"w":"engaged","tr":"nişanlı / meşgul","te":"Adjective","tt":"Sıfat","de":"Promised to marry or busy","dt":"Evlenmek üzere sözleşmiş veya meşgul","e1":"They got engaged last month.","e1t":"Geçen ay nişanlandılar.","e2":"The phone line is engaged.","e2t":"Telefon hattı meşgul."},{"w":"engine","tr":"motor","te":"Noun","tt":"İsim","de":"A machine that uses energy to create movement","dt":"Hareket yaratmak için enerji kullanan makine","e1":"Turn off the engine, please.","e1t":"Lütfen motoru kapat.","e2":"The car has a powerful engine.","e2t":"Arabanın güçlü bir motoru var."},{"w":"engineer","tr":"mühendis","te":"Noun","tt":"İsim","de":"A person who designs or builds machines/roads","dt":"Makine, yol veya binaları tasarlayan/inşa eden kişi","e1":"He wants to be a civil engineer.","e1t":"İnşaat mühendisi olmak istiyor.","e2":"The engineer fixed the problem.","e2t":"Mühendis sorunu düzeltti."},{"w":"engineering","tr":"mühendislik","te":"Noun","tt":"İsim","de":"The study of designing and building machines","dt":"Makine ve yapı tasarlama ve inşa etme bilimi","e1":"He is studying mechanical engineering.","e1t":"Makine mühendisliği okuyor.","e2":"Engineering is a popular career choice.","e2t":"Mühendislik popüler bir kariyer seçimidir."},{"w":"enjoy","tr":"zevk almak / eğlenmek","te":"Verb","tt":"Fiil","de":"To get pleasure from something","dt":"Bir şeyden keyif almak","e1":"I enjoy listening to music.","e1t":"Müzik dinlemekten zevk alıyorum.","e2":"Enjoy your meal!","e2t":"Afiyet olsun! (Yemeğinin tadını çıkar!)"},{"w":"enjoyable","tr":"keyifli","te":"Adjective","tt":"Sıfat","de":"Giving pleasure","dt":"Zevk veren","e1":"We had a very enjoyable evening.","e1t":"Çok keyifli bir akşam geçirdik.","e2":"Teaching can be an enjoyable job.","e2t":"Öğretmenlik keyifli bir iş olabilir."},{"w":"enormous","tr":"kocaman / devasa","te":"Adjective","tt":"Sıfat","de":"Very large in size or amount","dt":"Boyut veya miktar olarak çok büyük","e1":"The house has an enormous garden.","e1t":"Evin kocaman bir bahçesi var.","e2":"He made an enormous mistake.","e2t":"Devasa bir hata yaptı."},{"w":"enquiry / inquiry","tr":"soruşturma / sorgu","te":"Noun","tt":"İsim","de":"A request for information or an official investigation","dt":"Bilgi talebi veya resmi araştırma","e1":"I made an enquiry about the flight.","e1t":"Uçuş hakkında bir bilgi talebinde (sorgusunda) bulundum.","e2":"The police started an inquiry.","e2t":"Polis bir soruşturma başlattı."},{"w":"ensure","tr":"garantiye almak / sağlamak","te":"Verb","tt":"Fiil","de":"To make certain that something happens","dt":"Bir şeyin olacağından emin olmak","e1":"Please ensure that all doors are locked.","e1t":"Lütfen tüm kapıların kilitli olduğundan emin olun.","e2":"We must ensure the safety of the students.","e2t":"Öğrencilerin güvenliğini sağlamalıyız."},{"w":"enter","tr":"girmek","te":"Verb","tt":"Fiil","de":"To come or go into a place","dt":"Bir yere gelmek veya gitmek","e1":"Enter your password, please.","e1t":"Lütfen şifrenizi girin.","e2":"He entered the room quietly.","e2t":"Odaya sessizce girdi."},{"w":"entertain","tr":"eğlendirmek","te":"Verb","tt":"Fiil","de":"To interest and amuse people","dt":"İnsanların ilgisini çekmek ve onları eğlendirmek","e1":"He entertained the children with magic tricks.","e1t":"Sihirbazlık numaralarıyla çocukları eğlendirdi.","e2":"We love to entertain guests at home.","e2t":"Evde misafir ağırlamayı (eğlendirmeyi) severiz."},{"w":"entertainment","tr":"eğlence","te":"Noun","tt":"İsim","de":"Shows, films, or games that people enjoy","dt":"İnsanların zevk aldığı gösteriler, filmler veya oyunlar","e1":"There is live entertainment at the hotel.","e1t":"Otelde canlı eğlence var.","e2":"Cinema is a popular form of entertainment.","e2t":"Sinema popüler bir eğlence biçimidir."},{"w":"enthusiasm","tr":"coşku / heves","te":"Noun","tt":"İsim","de":"A strong feeling of excitement or interest","dt":"Güçlü bir heyecan veya ilgi duygusu","e1":"He showed great enthusiasm for the project.","e1t":"Proje için büyük bir coşku gösterdi.","e2":"I have lost my enthusiasm for the job.","e2t":"İşe olan hevesimi kaybettim."},{"w":"enthusiastic","tr":"hevesli","te":"Adjective","tt":"Sıfat","de":"Feeling or showing great excitement","dt":"Büyük heyecan duyan veya gösteren","e1":"She is enthusiastic about her new hobby.","e1t":"Yeni hobisi konusunda çok hevesli.","e2":"He gave an enthusiastic response.","e2t":"Coşkulu bir yanıt verdi."},{"w":"entire","tr":"tüm / bütün","te":"Adjective","tt":"Sıfat","de":"Whole or complete","dt":"Bütün veya tam","e1":"I spent the entire day cleaning.","e1t":"Tüm günü temizlik yaparak geçirdim.","e2":"The entire village was under water.","e2t":"Tüm köy sular altındaydı."},{"w":"entirely","tr":"tamamen","te":"Adverb","tt":"Zarf","de":"Completely","dt":"Bütünüyle","e1":"I entirely agree with you.","e1t":"Sana tamamen katılıyorum.","e2":"It was entirely my fault.","e2t":"Tamamen benim hatamdı."},{"w":"entrance","tr":"giriş","te":"Noun","tt":"İsim","de":"A door or gate that you go through to enter","dt":"Girmek için içinden geçtiğiniz kapı veya geçit","e1":"The main entrance is on the left.","e1t":"Ana giriş soldadır.","e2":"Wait for me at the entrance.","e2t":"Beni girişte bekle."},{"w":"entry","tr":"giriş / kayıt","te":"Noun","tt":"İsim","de":"The act of entering or an item in a list","dt":"Giriş eylemi veya listedeki bir madde","e1":"No entry without a ticket.","e1t":"Biletsiz giriş yoktur.","e2":"He made a new entry in his diary.","e2t":"Günlüğüne yeni bir kayıt (not) düştü."},{"w":"envelope","tr":"zarf","te":"Noun","tt":"İsim","de":"A flat paper container for letters","dt":"Mektuplar için düz kağıt kap","e1":"Put the letter in the envelope.","e1t":"Mektubu zarfa koy.","e2":"I need a large envelope.","e2t":"Büyük bir zarfa ihtiyacım var."},{"w":"environment","tr":"çevre","te":"Noun","tt":"İsim","de":"The natural world in which we live","dt":"İçinde yaşadığımız doğal dünya","e1":"We must protect the environment.","e1t":"Çevreyi korumalıyız.","e2":"It is a clean and safe environment.","e2t":"Temiz ve güvenli bir çevredir."},{"w":"environmental","tr":"çevresel","te":"Adjective","tt":"Sıfat","de":"Relating to the natural world","dt":"Doğal dünyayla ilgili olan","e1":"Pollution is a major environmental problem.","e1t":"Kirlilik büyük bir çevresel sorundur.","e2":"They are fighting for environmental protection.","e2t":"Çevrenin korunması için savaşıyorlar."},{"w":"episode","tr":"bölüm (dizi/olay)","te":"Noun","tt":"İsim","de":"A part of a TV show or a single event","dt":"Bir TV dizisinin parçası veya tekil bir olay","e1":"I missed the last episode of the series.","e1t":"Dizinin son bölümünü kaçırdım.","e2":"It was a strange episode in his life.","e2t":"Hayatında garip bir olaydı (bölümdü)."},{"w":"equal","tr":"eşit","te":"Adjective/Verb","tt":"Being the same in quantity, size, or value","de":"Miktar, boyut veya değer bakımından aynı olma","dt":"All people should have equal rights.","e1":"Tüm insanlar eşit haklara sahip olmalıdır.","e1t":"Two plus two equals four.","e2":"İki artı iki eşittir dört.","e2t":""},{"w":"equally","tr":"eşit olarak","te":"Adverb","tt":"Zarf","de":"In the same way or amount","dt":"Aynı şekilde veya miktarda","e1":"Divide the money equally between them.","e1t":"Parayı aralarında eşit olarak bölün.","e2":"They are both equally talented.","e2t":"İkisi de aynı derecede (eşit derecede) yetenekli."},{"w":"equation","tr":"denklem","te":"Noun","tt":"İsim","de":"A mathematical statement showing equality","dt":"Eşitliği gösteren matematiksel ifade","e1":"Can you solve this equation?","e1t":"Bu denklemi çözebilir misin?","e2":"is a famous equation.","e2t":"ünlü bir denklemdir."},{"w":"equipment","tr":"ekipman","te":"Noun","tt":"İsim","de":"The tools or machines needed for an activity","dt":"Bir aktivite için gereken araçlar veya makineler","e1":"We need new office equipment.","e1t":"Yeni ofis ekipmanına ihtiyacımız var.","e2":"Sports equipment is expensive.","e2t":"Spor ekipmanları pahalıdır."},{"w":"equivalent","tr":"eşdeğer","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Equal in value, amount, or meaning","dt":"Değer, miktar veya anlamca eşit","e1":"One dollar is equivalent to about 30 liras.","e1t":"Bir dolar yaklaşık 30 liraya eşdeğerdir.","e2":"There is no English equivalent for this word.","e2t":"Bu kelimenin İngilizce bir karşılığı (eşdeğeri) yok."},{"w":"era","tr":"dönem / çağ","te":"Noun","tt":"İsim","de":"A long and distinct period of history","dt":"Tarihin uzun ve belirgin bir dönemi","e1":"We are living in the space era.","e1t":"Uzay çağında yaşıyoruz.","e2":"The Victorian era was a time of change.","e2t":"Viktorya dönemi bir değişim zamanıydı."},{"w":"erase","tr":"silmek","te":"Verb","tt":"Fiil","de":"To remove written words or a memory","dt":"Yazılı kelimeleri veya bir anıyı silmek","e1":"You can erase the pencil marks.","e1t":"Kurşun kalem izlerini silebilirsin.","e2":"He tried to erase the memory of the accident.","e2t":"Kaza anısını silmeye çalıştı."},{"w":"error","tr":"hata","te":"Noun","tt":"İsim","de":"A mistake or something that is wrong","dt":"Bir yanlış veya hatalı olan bir şey","e1":"There is an error in your report.","e1t":"Raporunuzda bir hata var.","e2":"The system shows a connection error.","e2t":"Sistem bir bağlantı hatası gösteriyor."},{"w":"escape","tr":"kaçmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get free from a place or danger","dt":"Bir yerden veya tehlikeden kurtulmak","e1":"The bird escaped from the cage.","e1t":"Kuş kafesten kaçtı.","e2":"It was a narrow escape.","e2t":"Kıl payı bir kurtuluştu."},{"w":"especially","tr":"özellikle","te":"Adverb","tt":"Zarf","de":"Used to single out one person or thing","dt":"Bir kişiyi veya şeyi öne çıkarmak için kullanılır","e1":"I love fruit, especially strawberries.","e1t":"Meyveyi severim, özellikle çileği.","e2":"It is very hot today, especially in the afternoon.","e2t":"Bugün hava çok sıcak, özellikle öğleden sonra."},{"w":"essay","tr":"kısa yazı / makale","te":"Noun","tt":"İsim","de":"A short piece of writing on a subject","dt":"Bir konu üzerine yazılmış kısa yazı","e1":"I have to write an essay about history.","e1t":"Tarih hakkında bir makale (essay) yazmam gerekiyor.","e2":"Her essay was very good.","e2t":"Onun makalesi çok iyiydi."},{"w":"essential","tr":"gerekli","te":"Adjective","tt":"Sıfat","de":"Completely necessary or extremely important","dt":"Tamamen gerekli veya son derece önemli","e1":"Water is essential for life.","e1t":"Su yaşam için temeldir (gereklidir).","e2":"It is essential to arrive on time.","e2t":"Vaktinde varmak çok önemlidir."},{"w":"essentially","tr":"esasen / aslında","te":"Adverb","tt":"Zarf","de":"Relating to the basic nature of something","dt":"Bir şeyin temel doğasıyla ilgili","e1":"It is essentially a simple problem.","e1t":"Bu esasen basit bir problemdir.","e2":"The two plans are essentially the same.","e2t":"İki plan aslında aynıdır."},{"w":"establish","tr":"kurmak / belirlemek","te":"Verb","tt":"Fiil","de":"To start a company or a relationship","dt":"Bir şirket veya ilişki başlatmak (kurmak)","e1":"The company was established in 1950.","e1t":"Şirket 1950'de kuruldu.","e2":"We need to establish the facts.","e2t":"Gerçekleri belirlemeliyiz."},{"w":"establishment","tr":"kuruluş / kurum","te":"Noun","tt":"İsim","de":"The act of starting something or an organization","dt":"Bir şeyi başlatma eylemi veya bir organizasyon/kurum","e1":"The establishment of the new school took two years.","e1t":"Yeni okulun kurulması iki yıl sürdü.","e2":"This is a well","e2t":"known educational establishment."},{"w":"estate","tr":"mülk / emlak","te":"Noun","tt":"İsim","de":"A large area of land or a person's property","dt":"Büyük bir arazi alanı veya birinin mülkiyeti","e1":"He lives on a large country estate.","e1t":"Büyük bir kır mülkünde yaşıyor.","e2":"He works in real estate.","e2t":"Emlak işinde (gayrimenkulde) çalışıyor."},{"w":"estimate","tr":"tahmin etmek / değer biçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To guess the value or cost of something","dt":"Bir şeyin değerini veya maliyetini tahmin etmek","e1":"They estimate that the project will cost $10,000.","e1t":"Projenin 10.000 dolara mal olacağını tahmin ediyorlar.","e2":"Can you give me a written estimate?","e2t":"Bana yazılı bir fiyat tahmini verebilir misin?"},{"w":"estimation","tr":"tahmin / kanaat","te":"Noun","tt":"İsim","de":"A judgment or a calculated guess","dt":"Bir yargı veya hesaplanmış tahmin","e1":"In my estimation, he is the best candidate.","e1t":"Benim kanaatime göre o en iyi adaydır.","e2":"The estimation was correct.","e2t":"Tahmin doğruydu."},{"w":"etc. (et cetera)","tr":"ve benzeri / vesaire","te":"Adverb","tt":"Zarf","de":"And other similar things","dt":"Ve diğer benzer şeyler","e1":"I need fruit: apples, oranges, bananas, etc.","e1t":"Meyveye ihtiyacım var: elma, portakal, muz vb.","e2":"They sell pens, paper, etc.","e2t":"Kalem, kağıt vb. satıyorlar."},{"w":"ethical","tr":"etik / ahlaki","te":"Adjective","tt":"Sıfat","de":"Relating to beliefs about right and wrong","dt":"Doğru ve yanlış hakkındaki inançlarla ilgili","e1":"Is it ethical to test products on animals?","e1t":"Ürünleri hayvanlar üzerinde test etmek etik mi?","e2":"He is an ethical businessman.","e2t":"O etik (ahlaklı) bir iş adamıdır."},{"w":"ethics","tr":"etik / ahlak kuralları","te":"Noun","tt":"İsim","de":"Moral principles that control behavior","dt":"Davranışları kontrol eden ahlaki ilkeler","e1":"Medical ethics are very important.","e1t":"Tıbbi etik çok önemlidir.","e2":"We discussed the ethics of the situation.","e2t":"Durumun etiğini tartıştık."},{"w":"ethnic","tr":"etnik","te":"Adjective","tt":"Sıfat","de":"Relating to a group with shared culture/race","dt":"Paylaşılan kültür/ırka sahip bir grupla ilgili","e1":"There are many ethnic groups in London.","e1t":"Londra'da birçok etnik grup var.","e2":"I love trying ethnic food.","e2t":"Etnik yemekleri denemeyi severim."},{"w":"euro","tr":"Euro","te":"Noun","tt":"İsim","de":"The unit of money used in many European countries","dt":"Birçok Avrupa ülkesinde kullanılan para birimi","e1":"The coffee costs three Euros.","e1t":"Kahve üç Euro tutuyor.","e2":"Can I pay in Euros?","e2t":"Euro ile ödeyebilir miyim?"},{"w":"europe","tr":"Avrupa","te":"Noun","tt":"İsim","de":"The continent located to the west of Asia","dt":"Asya'nın batısında yer alan kıta","e1":"France and Germany are in Europe.","e1t":"Fransa ve Almanya Avrupa'dadır.","e2":"I want to travel across Europe.","e2t":"Avrupa genelinde seyahat etmek istiyorum."},{"w":"european","tr":"Avrupalı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to Europe or a person from Europe","dt":"Avrupa ile ilgili veya Avrupalı kişi","e1":"The European Union has many members.","e1t":"Avrupa Birliği'nin birçok üyesi var.","e2":"He is a European citizen.","e2t":"O bir Avrupa vatandaşıdır."},{"w":"evaluate","tr":"değerlendirmek","te":"Verb","tt":"Fiil","de":"To judge the quality or value of something","dt":"Bir şeyin kalitesini veya değerini yargılamak","e1":"We need to evaluate the results.","e1t":"Sonuçları değerlendirmemiz gerekiyor.","e2":"How do you evaluate your students?","e2t":"Öğrencilerinizi nasıl değerlendirirsiniz?"},{"w":"evaluation","tr":"değerlendirme","te":"Noun","tt":"İsim","de":"The act of judging something","dt":"Bir şeyi değerlendirme eylemi","e1":"The teacher gave us a final evaluation.","e1t":"Öğretmen bize son bir değerlendirme yaptı.","e2":"Performance evaluation is done every year.","e2t":"Performans değerlendirmesi her yıl yapılır."},{"w":"even","tr":"bile / hatta / çift (sayı)","te":"Adverb/Adjective","tt":"Used to emphasize or divisible by two","de":"Vurgulamak için kullanılır veya ikiye bölünebilen","dt":"He didn't even say goodbye.","e1":"Hoşça kal bile demedi.","e1t":"Two, four, and six are even numbers.","e2":"İki, dört ve altı çift sayılardır.","e2t":""},{"w":"event","tr":"etkinlik","te":"Noun","tt":"İsim","de":"A planned social or public occasion","dt":"Planlanmış sosyal veya halka açık durum","e1":"The wedding was a big event.","e1t":"Düğün büyük bir etkinlikti.","e2":"What are the main events this week?","e2t":"Bu haftanın ana etkinlikleri neler?"},{"w":"eventually","tr":"sonunda / nihayetinde","te":"Adverb","tt":"Zarf","de":"In the end, especially after a long time","dt":"Sonunda, özellikle uzun bir süre sonra","e1":"He eventually passed the test.","e1t":"Sonunda sınavı geçti.","e2":"We will get there eventually.","e2t":"Oraya nihayetinde varacağız."},{"w":"ever","tr":"hiç / her zaman","te":"Adverb","tt":"Zarf","de":"At any time","dt":"Herhangi bir zamanda","e1":"Have you ever been to London?","e1t":"Hiç Londra'da bulundun mu?","e2":"This is the best movie ever!","e2t":"Bu gelmiş geçmiş en iyi film!"},{"w":"every","tr":"her","te":"Determiner","tt":"Belirleyici","de":"All the people or things in a group","dt":"Bir gruptaki tüm insanlar veya şeyler","e1":"I go to the gym every day.","e1t":"Her gün spor salonuna giderim.","e2":"Every student must sign the form.","e2t":"Her öğrenci formu imzalamalıdır."},{"w":"everybody","tr":"herkes","te":"Pronoun","tt":"Zamir","de":"Every person; everyone","dt":"Her kişi; herkes","e1":"Everybody is happy today.","e1t":"Bugün herkes mutlu.","e2":"Does everybody understand?","e2t":"Herkes anlıyor mu?"},{"w":"everyday","tr":"günlük / sıradan","te":"Adjective","tt":"Sıfat","de":"Ordinary; happening every day","dt":"Sıradan; her gün olan","e1":"These are my everyday shoes.","e1t":"Bunlar benim günlük ayakkabılarım.","e2":"Stress is a part of everyday life.","e2t":"Stres günlük hayatın bir parçasıdır."},{"w":"everyone","tr":"herkes","te":"Pronoun","tt":"Zamir","de":"Every person","dt":"Her kişi","e1":"Everyone enjoyed the party.","e1t":"Herkes partiden zevk aldı.","e2":"I hope everyone is okay.","e2t":"Umarım herkes iyidir."},{"w":"everything","tr":"her şey","te":"Pronoun","tt":"Zamir","de":"All things","dt":"Tüm şeyler","e1":"Everything is ready for the trip.","e1t":"Yolculuk için her şey hazır.","e2":"Money isn't everything.","e2t":"Para her şey değildir."},{"w":"everywhere","tr":"her yerde","te":"Adverb","tt":"Zarf","de":"In all places","dt":"Tüm yerlerde","e1":"I looked everywhere for my keys.","e1t":"Anahtarlarımı her yerde aradım.","e2":"There were flowers everywhere.","e2t":"Her yerde çiçekler vardı."},{"w":"evidence","tr":"kanıt","te":"Noun","tt":"İsim","de":"Facts or signs that show something is true","dt":"Bir şeyin doğru olduğunu gösteren gerçekler veya işaretler","e1":"There is no evidence against him.","e1t":"Onun aleyhinde hiçbir kanıt yok.","e2":"The police found evidence at the scene.","e2t":"Polis olay yerinde kanıt buldu."},{"w":"evil","tr":"kötü / kötülük","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Very bad or harmful","dt":"Çok kötü veya zararlı","e1":"He is an evil man.","e1t":"O kötü bir adamdır.","e2":"The battle between good and evil.","e2t":"İyi ve kötü arasındaki savaş."},{"w":"evolution","tr":"evrim","te":"Noun","tt":"İsim","de":"The gradual development of something","dt":"Bir şeyin kademeli gelişimi","e1":"Darwin's theory of evolution.","e1t":"Darwin'in evrim teorisi.","e2":"The evolution of technology is fast.","e2t":"Teknolojinin evrimi (gelişimi) hızlıdır."},{"w":"evolve","tr":"evrilmek / gelişmek","te":"Verb","tt":"Fiil","de":"To develop gradually","dt":"Kademeli olarak gelişmek","e1":"Humans evolved over millions of years.","e1t":"İnsanlar milyonlarca yıl içinde evrildi.","e2":"The software continues to evolve.","e2t":"Yazılım gelişmeye devam ediyor."},{"w":"exact","tr":"tam, kesin","te":"Adjective","tt":"Sıfat","de":"Completely correct in every detail","dt":"Her detayda tamamen doğru olan","e1":"What is the exact price?","e1t":"Tam fiyat nedir?","e2":"I need the exact measurements.","e2t":"Tam (kesin) ölçülere ihtiyacım var."},{"w":"exactly","tr":"tam olarak","te":"Adverb","tt":"Zarf","de":"In an exact way","dt":"Tam bir şekilde","e1":"It is exactly 10 o'clock.","e1t":"Saat tam olarak 10.","e2":"That's exactly what I meant.","e2t":"Tam olarak demek istediğim buydu."},{"w":"exaggerate","tr":"abartmak","te":"Verb","tt":"Fiil","de":"To make something seem larger or better/worse","dt":"Bir şeyi olduğundan büyük, iyi veya kötü göstermek","e1":"Don't exaggerate, it wasn't that bad.","e1t":"Abartma, o kadar da kötü değildi.","e2":"He tends to exaggerate his achievements.","e2t":"Başarılarını abartma eğilimindedir."},{"w":"exam / examination","tr":"sınav / inceleme","te":"Noun","tt":"İsim","de":"A formal test of knowledge or a detailed look","dt":"Resmi bilgi testi veya detaylı bakış","e1":"I passed my English exam.","e1t":"İngilizce sınavımı geçtim.","e2":"The doctor did a careful examination.","e2t":"Doktor dikkatli bir inceleme yaptı."},{"w":"examine","tr":"incelemek / muayene etmek","te":"Verb","tt":"Fiil","de":"To look at something carefully","dt":"Bir şeye dikkatlice bakmak","e1":"The doctor examined the patient.","e1t":"Doktor hastayı muayene etti.","e2":"Let's examine the data.","e2t":"Verileri inceleyelim."},{"w":"example","tr":"örnek","te":"Noun","tt":"İsim","de":"Something that shows what a group is like","dt":"Bir grubun nasıl olduğunu gösteren şey","e1":"Can you give me an example?","e1t":"Bana bir örnek verebilir misin?","e2":"For example, look at this picture.","e2t":"Örneğin, bu resme bak."},{"w":"excellent","tr":"mükemmel","te":"Adjective","tt":"Sıfat","de":"Extremely good or outstanding","dt":"Son derece iyi veya göze çarpan","e1":"This is an excellent idea.","e1t":"Bu mükemmel bir fikir.","e2":"The service was excellent.","e2t":"Hizmet mükemmeldi."},{"w":"except","tr":"hariç","te":"Preposition/Conjunction","tt":"Not including; other than","de":"Dahil etmeden; ... dışında","dt":"Everyone was there except John.","e1":"John hariç herkes oradaydı.","e1t":"The shop is open every day except Sunday.","e2":"Dükkan pazar hariç her gün açık.","e2t":""},{"w":"exception","tr":"istisna","te":"Noun","tt":"İsim","de":"Someone or something that is not included","dt":"Dahil edilmeyen bir kişi veya şey","e1":"There is an exception to every rule.","e1t":"Her kuralın bir istisnası vardır.","e2":"With the exception of one student, everyone passed.","e2t":"Bir öğrenci istisnasıyla (hariç), herkes geçti."},{"w":"exchange","tr":"takas / döviz / değiş tokuş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give something and get something else","dt":"Bir şeyi verip başka bir şey almak","e1":"I want to exchange some dollars for liras.","e1t":"Biraz doları liraya çevirmek (takas etmek) istiyorum.","e2":"We had a brief exchange of ideas.","e2t":"Kısa bir fikir alışverişinde bulunduk."},{"w":"excited","tr":"heyecanlı","te":"Adjective","tt":"Sıfat","de":"Feeling very happy and enthusiastic","dt":"Çok mutlu ve hevesli hissetme","e1":"The children are excited about the party.","e1t":"Çocuklar parti için heyecanlılar.","e2":"I am excited to start my new job.","e2t":"Yeni işime başlayacağım için heyecanlıyım."},{"w":"excitement","tr":"heyecan","te":"Noun","tt":"İsim","de":"A feeling of being excited","dt":"Heyecanlı olma durumu","e1":"There was a lot of excitement in the air.","e1t":"Havada büyük bir heyecan vardı.","e2":"He couldn't hide his excitement.","e2t":"Heyecanını gizleyemedi."},{"w":"exciting","tr":"heyecan verici","te":"Adjective","tt":"Sıfat","de":"Making you feel excited","dt":"Sizi heyecanlandıran","e1":"This is an exciting movie.","e1t":"Bu heyecan verici bir film.","e2":"I have some exciting news.","e2t":"Heyecan verici haberlerim var."},{"w":"exclude","tr":"hariç tutmak / dışlamak","te":"Verb","tt":"Fiil","de":"To not include someone or something","dt":"Birini veya bir şeyi dahil etmemek","e1":"The price excludes taxes.","e1t":"Fiyat vergileri hariç tutar (dahil değildir).","e2":"They excluded him from the meeting.","e2t":"Onu toplantının dışında bıraktılar (dışladılar)."},{"w":"excuse","tr":"bahane / affetmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A reason given to explain a mistake or to forgive","dt":"Bir hatayı açıklamak için verilen sebep veya affetmek","e1":"He made an excuse for being late.","e1t":"Geç kaldığı için bir bahane uydurdu.","e2":"Excuse me, where is the station?","e2t":"Affedersiniz, istasyon nerede?"},{"w":"executive","tr":"yönetici / yürütme","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person in charge of a business","dt":"Bir işin sorumlusu olan kişi","e1":"He is a senior executive at the company.","e1t":"O, şirkette üst düzey bir yöneticidir.","e2":"The executive branch of the government.","e2t":"Hükümetin yürütme organı."},{"w":"exercise","tr":"egzersiz","te":"Noun/Verb","tt":"İsim/Fiil","de":"Physical activity to stay healthy","dt":"Sağlıklı kalmak için yapılan fiziksel aktivite","e1":"You should do more exercise.","e1t":"Daha fazla egzersiz yapmalısın.","e2":"I exercise for 30 minutes every morning.","e2t":"Her sabah 30 dakika egzersiz yaparım."},{"w":"exhibit","tr":"sergilemek / sergi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To show something in public or an object shown","dt":"Bir şeyi halka göstermek veya gösterilen nesne","e1":"The artist is exhibiting his new paintings.","e1t":"Sanatçı yeni tablolarını sergiliyor.","e2":"Don't touch the exhibits.","e2t":"Sergilenen nesnelere dokunmayın."},{"w":"exhibition","tr":"sergi","te":"Noun","tt":"İsim","de":"A public show of art or objects","dt":"Sanat veya nesnelerin halka açık gösterimi","e1":"We went to a photo exhibition.","e1t":"Bir fotoğraf sergisine gittik.","e2":"The exhibition ends next Friday.","e2t":"Sergi gelecek cuma bitiyor."},{"w":"exist","tr":"var olmak","te":"Verb","tt":"Fiil","de":"To be real or to live","dt":"Gerçek olmak veya yaşamak","e1":"Do you believe that aliens exist?","e1t":"Uzaylıların var olduğuna inanıyor musun?","e2":"Life cannot exist without water.","e2t":"Su olmadan yaşam var olamaz."},{"w":"existence","tr":"varlık / mevcudiyet","te":"Noun","tt":"Isim","de":"The state of existing","dt":"Var olma durumu","e1":"Science explains the existence of the universe.","e1t":"Bilim evrenin varlığını açıklar.","e2":"He leads a quiet existence.","e2t":"Sessiz bir yaşam (varlık) sürüyor."},{"w":"exit","tr":"çıkış","te":"Noun/Verb","tt":"İsim/Fiil","de":"A way out or to leave","dt":"Dışarı çıkan yol veya ayrılmak","e1":"Where is the emergency exit?","e1t":"Acil çıkış nerede?","e2":"Please exit the building quietly.","e2t":"Lütfen binadan sessizce çıkın (ayrılın)."},{"w":"expand","tr":"genişlemek / büyümek","te":"Verb","tt":"Fiil","de":"To become larger in size or amount","dt":"Boyut veya miktar olarak daha büyük olmak","e1":"The metal expands when heated.","e1t":"Metal ısıtıldığında genleşir (genişler).","e2":"The company is expanding into new markets.","e2t":"Şirket yeni pazarlara açılıyor (büyüyor)."},{"w":"expansion","tr":"genişleme / büyüme","te":"Noun","tt":"İsim","de":"The act of becoming larger","dt":"Daha büyük olma eylemi","e1":"The expansion of the city is very fast.","e1t":"Şehrin büyümesi çok hızlı.","e2":"We are planning a business expansion.","e2t":"Bir iş büyümesi (genişlemesi) planlıyoruz."},{"w":"expect","tr":"beklemek","te":"Verb","tt":"Fiil","de":"To think that something will happen","dt":"Bir şeyin olacağını düşünmek (ummak)","e1":"I expect that he will be late.","e1t":"Onun geç kalacağını tahmin ediyorum (bekliyorum).","e2":"What do you expect from me?","e2t":"Benden ne bekliyorsun?"},{"w":"expectation","tr":"beklenti","te":"Noun","tt":"İsim","de":"A hope or belief about the future","dt":"Gelecek hakkındaki umut veya inanç","e1":"The movie didn't meet my expectations.","e1t":"Film beklentilerimi karşılamadı.","e2":"He has high expectations for his kids.","e2t":"Çocukları için yüksek beklentileri var."},{"w":"expected","tr":"beklenen","te":"Adjective","tt":"Sıfat","de":"Thought to be likely to happen","dt":"Olması muhtemel görülen","e1":"It was an expected result.","e1t":"Beklenen bir sonuçtu.","e2":"The rain is expected tonight.","e2t":"Bu gece yağmur bekleniyor."},{"w":"expense","tr":"masraf / gider","te":"Noun","tt":"İsim","de":"The money spent on something","dt":"Bir şeye harcanan para","e1":"Travel expenses are high.","e1t":"Seyahat masrafları yüksek.","e2":"At the expense of his health.","e2t":"Sağlığı pahasına (gideriyle)."},{"w":"expensive","tr":"pahalı","te":"Adjective","tt":"Sıfat","de":"Costing a lot of money","dt":"Çok para tutan","e1":"This car is too expensive for me.","e1t":"Bu araba benim için çok pahalı.","e2":"Gold is an expensive metal.","e2t":"Altın pahalı bir metaldir."},{"w":"experience","tr":"deneyim","te":"Noun/Verb","tt":"İsim/Fiil","de":"Knowledge or skill gained from doing something","dt":"Bir şeyi yapmaktan elde edilen bilgi veya beceri","e1":"He has a lot of experience in teaching.","e1t":"Öğretmenlikte çok tecrübesi var.","e2":"Travel is a great experience.","e2t":"Seyahat harika bir deneyimdir."},{"w":"experienced","tr":"deneyimli","te":"Adjective","tt":"Sıfat","de":"Having knowledge or skill from practice","dt":"Uygulamadan gelen bilgi veya beceriye sahip olma","e1":"He is an experienced pilot.","e1t":"O deneyimli bir pilottur.","e2":"We need an experienced manager.","e2t":"Deneyimli bir müdüre ihtiyacımız var."},{"w":"experiment","tr":"deney","te":"Noun/Verb","tt":"İsim/Fiil","de":"A scientific test to discover something","dt":"Bir şeyi keşfetmek için yapılan bilimsel test","e1":"We did an experiment in the chemistry class.","e1t":"Kimya dersinde bir deney yaptık.","e2":"The experiment was successful.","e2t":"Deney başarılıydı."},{"w":"expert","tr":"uzman","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person with special knowledge or skill","dt":"Özel bilgi veya beceriye sahip kişi","e1":"He is an expert in computer technology.","e1t":"O, bilgisayar teknolojisinde bir uzmandır.","e2":"You should ask an expert.","e2t":"Bir uzmana sormalısın."},{"w":"expertise","tr":"uzmanlık","te":"Noun","tt":"İsim","de":"High level of knowledge or skill","dt":"Üst düzey bilgi veya beceri","e1":"She has expertise in marketing.","e1t":"Pazarlama konusunda uzmanlığı var.","e2":"We value your technical expertise.","e2t":"Teknik uzmanlığınıza değer veriyoruz."},{"w":"explain","tr":"açıklamak","te":"Verb","tt":"Fiil","de":"To make something clear or easy to understand","dt":"Bir şeyi net veya anlaşılması kolay hale getirmek","e1":"Can you explain this rule to me?","e1t":"Bu kuralı bana açıklayabilir misin?","e2":"He explained why he was late.","e2t":"Neden geç kaldığını açıkladı."},{"w":"explanation","tr":"açıklama","te":"Noun","tt":"İsim","de":"A statement that makes something clear","dt":"Bir şeyi netleştiren ifade","e1":"His explanation was very clear.","e1t":"Onun açıklaması çok netti.","e2":"I need an explanation for this mistake.","e2t":"Bu hata için bir açıklamaya ihtiyacım var."},{"w":"explode","tr":"patlamak","te":"Verb","tt":"Fiil","de":"To burst or shatter violently","dt":"Şiddetli bir şekilde parçalanmak veya patlamak","e1":"The bomb exploded at midnight.","e1t":"Bomba gece yarısı patladı.","e2":"My head feels like it's going to explode.","e2t":"Başım patlayacakmış gibi hissediyorum."},{"w":"explore","tr":"keşfetmek / araştırmak","te":"Verb","tt":"Fiil","de":"To travel to or search a place to learn about it","dt":"Bir yeri öğrenmek için seyahat etmek veya aramak","e1":"Let's explore the old city.","e1t":"Eski şehri keşfedelim.","e2":"We need to explore all the options.","e2t":"Tüm seçenekleri araştırmalıyız."},{"w":"explosion","tr":"patlama","te":"Noun","tt":"İsim","de":"A sudden and violent burst","dt":"Ani ve şiddetli bir patlama","e1":"We heard a loud explosion.","e1t":"Büyük bir patlama duyduk.","e2":"There was an explosion of interest in AI.","e2t":"Yapay zekaya olan ilgide bir patlama yaşandı."},{"w":"export","tr":"ihraç etmek / ihracat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To send goods to another country","dt":"Başka bir ülkeye mal göndermek","e1":"Turkey exports many textile products.","e1t":"Türkiye birçok tekstil ürünü ihraç ediyor.","e2":"Oil is their main export.","e2t":"Petrol onların ana ihracatıdır."},{"w":"expose","tr":"maruz bırakmak / açığa çıkarmak","te":"Verb","tt":"Fiil","de":"To reveal or leave unprotected","dt":"Ortaya çıkarmak veya korumasız bırakmak","e1":"Don't expose your skin to the sun for too long.","e1t":"Cildinizi güneşe çok uzun süre maruz bırakmayın.","e2":"The report exposed the truth.","e2t":"Rapor gerçeği açığa çıkardı."},{"w":"express","tr":"ifade etmek / hızlı","te":"Verb/Adjective/Noun","tt":"To show a feeling or very fast","de":"Bir duyguyu göstermek veya çok hızlı","dt":"He found it difficult to express his feelings.","e1":"Duygularını ifade etmeyi zor buldu.","e1t":"This is an express train.","e2":"Bu bir ekspres (hızlı) trendir.","e2t":""},{"w":"expression","tr":"ifade","te":"Noun","tt":"İsim","de":"A look on someone's face or a group of words","dt":"Birinin yüzündeki bakış veya bir kelime grubu","e1":"He had a strange expression on his face.","e1t":"Yüzünde garip bir ifade vardı.","e2":"'Break a leg' is a common expression.","e2t":"'Break a leg' (başarılar) yaygın bir ifadedir."},{"w":"extend","tr":"uzatmak / genişletmek","te":"Verb","tt":"Fiil","de":"To make something longer or larger","dt":"Bir şeyi daha uzun veya daha büyük yapmak","e1":"Can you extend the deadline?","e1t":"Son teslim tarihini uzatabilir misiniz?","e2":"We want to extend our garden.","e2t":"Bahçemizi genişletmek istiyoruz."},{"w":"extension","tr":"uzantı / dahili hat","te":"Noun","tt":"İsim","de":"An extra part or a telephone line","dt":"Ek bir parça veya telefon hattı","e1":"I need an extension for my project.","e1t":"Projem için ek süre (uzatma) istiyorum.","e2":"My telephone extension is 123.","e2t":"Dahili telefon numaram 123."},{"w":"extensive","tr":"kapsamlı / yaygın","te":"Adjective","tt":"Sıfat","de":"Covering a large area or having a great range","dt":"Geniş bir alanı kapsayan veya büyük bir yelpazesi olan","e1":"The storm caused extensive damage.","e1t":"Fırtına kapsamlı (yaygın) hasara yol açtı.","e2":"He has extensive knowledge of history.","e2t":"Geniş bir tarih bilgisi var."},{"w":"extent","tr":"kapsam / derece","te":"Noun","tt":"İsim","de":"The area or length of something; degree","dt":"Bir şeyin alanı veya uzunluğu; derece","e1":"I agree with you to a certain extent.","e1t":"Sana belirli bir dereceye kadar katılıyorum.","e2":"What is the extent of the damage?","e2t":"Hasarın boyutu (kapsamı) nedir?"},{"w":"external","tr":"harici / dış","te":"Adjective","tt":"Sıfat","de":"Relating to the outside of something","dt":"Bir şeyin dışıyla ilgili olan","e1":"This medicine is for external use only.","e1t":"Bu ilaç sadece harici kullanım içindir.","e2":"The company uses an external consultant.","e2t":"Şirket dışarıdan bir danışman kullanıyor."},{"w":"extra","tr":"ekstra","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"More than what is usual or expected","dt":"Olağan veya beklenenden daha fazla","e1":"Do you need an extra bed?","e1t":"Fazladan (ekstra) bir yatağa ihtiyacın var mı?","e2":"The job will take extra time.","e2t":"İş ekstra zaman alacak."},{"w":"extraordinary","tr":"olağanüstü","te":"Adjective","tt":"Sıfat","de":"Very unusual or remarkable","dt":"Çok alışılmadık veya dikkat çekici","e1":"She is an extraordinary teacher.","e1t":"O olağanüstü bir öğretmendir.","e2":"What an extraordinary story!","e2t":"Ne olağanüstü bir hikaye!"},{"w":"extreme","tr":"aşırı","te":"Adjective","tt":"Sıfat","de":"Very great in degree or intensity","dt":"Derece veya yoğunluk olarak çok büyük","e1":"The weather conditions were extreme.","e1t":"Hava koşulları aşırıydı.","e2":"He likes extreme sports.","e2t":"O aşırı (ekstrem) sporları sever."},{"w":"extremely","tr":"son derece","te":"Adverb","tt":"Zarf","de":"To a very high degree","dt":"Çok yüksek bir derecede","e1":"It is extremely cold today.","e1t":"Bugün hava son derece soğuk.","e2":"I am extremely busy.","e2t":"Son derece meşgulüm."},{"w":"eyebrow","tr":"kaş","te":"Noun","tt":"İsim","de":"The line of hair above the eye","dt":"Gözün üzerindeki tüy sırası","e1":"He raised an eyebrow in surprise.","e1t":"Şaşkınlıkla bir kaşını kaldırdı.","e2":"She has thick eyebrows.","e2t":"Kalın kaşları var."},{"w":"eyelash","tr":"kirpik","te":"Noun","tt":"İsim","de":"One of the short hairs on the edge of the eyelid","dt":"Göz kapağının kenarındaki kısa tüylerden her biri","e1":"A piece of dust got on my eyelash.","e1t":"Kirpiğime bir toz parçası kaçtı.","e2":"She has long eyelashes.","e2t":"Uzun kirpikleri var."},{"w":"facility","tr":"tesis / olanak","te":"Noun","tt":"İsim","de":"A building or service provided for a purpose","dt":"Bir amaç için sağlanan bina veya hizmet","e1":"The hotel has great sports facilities.","e1t":"Otelin harika spor tesisleri var.","e2":"There are new medical facilities in the city.","e2t":"Şehirde yeni tıbbi olanaklar var."},{"w":"factor","tr":"faktör / etken","te":"Noun","tt":"İsim","de":"One of the things that influence a result","dt":"Bir sonucu etkileyen şeylerden biri","e1":"Diet is an important factor in health.","e1t":"Diyet, sağlıkta önemli bir faktördür.","e2":"Several factors led to the accident.","e2t":"Kazaya birkaç etken sebep oldu."},{"w":"factory","tr":"fabrika","te":"Noun","tt":"İsim","de":"A building where goods are made by machines","dt":"Malların makinelerle yapıldığı bina","e1":"He works in a car factory.","e1t":"Bir araba fabrikasında çalışıyor.","e2":"The factory produces toys.","e2t":"Fabrika oyuncak üretiyor."},{"w":"faculty","tr":"fakülte / yetenek","te":"Noun","tt":"İsim","de":"A department of a university or a natural power","dt":"Üniversite bölümü veya doğal yetenek","e1":"He is a student at the Faculty of Law.","e1t":"Hukuk Fakültesi'nde öğrencidir.","e2":"He lost his mental faculties.","e2t":"Zihinsel melekelerini (yeteneklerini) kaybetti."},{"w":"fade","tr":"solmak / hafiflemek","te":"Verb","tt":"Fiil","de":"To lose color or strength gradually","dt":"Rengini veya gücünü kademeli olarak kaybetmek","e1":"The sun caused the curtains to fade.","e1t":"Güneş perdelerin solmasına neden oldu.","e2":"The sound faded away.","e2t":"Ses yavaşça yok oldu (hafifledi)."},{"w":"fail","tr":"başarısız olmak","te":"Verb","tt":"Fiil","de":"To not succeed in doing something","dt":"Bir şeyi yapmada başarılı olamamak","e1":"I failed my driving test.","e1t":"Direksiyon sınavında başarısız oldum (kaldım).","e2":"Don't be afraid to fail.","e2t":"Başarısız olmaktan korkma."},{"w":"failure","tr":"başarısızlık","te":"Noun","tt":"İsim","de":"Lack of success","dt":"Başarı eksikliği","e1":"The project was a total failure.","e1t":"Proje tam bir başarısızlıktı.","e2":"Failure is a part of learning.","e2t":"Başarısızlık öğrenmenin bir parçasıdır."},{"w":"faint","tr":"bayılmak / hafif","te":"Verb/Adjective","tt":"To lose consciousness or not clear/strong","de":"Bilincini kaybetmek veya net/güçlü olmayan","dt":"I felt faint because of the heat.","e1":"Sıcaktan dolayı bayılacak gibi hissettim.","e1t":"I heard a faint noise.","e2":"Hafif bir ses duydum.","e2t":""},{"w":"fair","tr":"adil","te":"Adjective","tt":"Sıfat","de":"Treating everyone in the same way","dt":"Herkese aynı şekilde davranan","e1":"That's not fair!","e1t":"Bu adil değil!","e2":"He is a fair teacher.","e2t":"O adil bir öğretmendir."},{"w":"fairly","tr":"oldukça / adilce","te":"Adverb","tt":"Zarf","de":"To a moderate degree or in a fair way","dt":"Orta derecede veya adil bir şekilde","e1":"The test was fairly difficult.","e1t":"Test oldukça zordu.","e2":"Everyone should be treated fairly.","e2t":"Herkese adilce davranılmalı."},{"w":"faith","tr":"inanç / güven","te":"Noun","tt":"İsim","de":"Trust or a strong religious belief","dt":"Güven veya güçlü dini inanç","e1":"I have faith in you.","e1t":"Sana inancım (güvenim) var.","e2":"Religion is based on faith.","e2t":"Din inanca dayanır."},{"w":"faithful","tr":"sadık","te":"Adjective","tt":"Sıfat","de":"Loyal and firm in support","dt":"Sadık ve destek konusunda kararlı","e1":"He is a faithful friend.","e1t":"O sadık bir arkadaştır.","e2":"The dog is a faithful companion.","e2t":"Köpek sadık bir dosttur."},{"w":"fake","tr":"sahte","te":"Adjective/Noun/Verb","tt":"Not real; made to look like something else","de":"Gerçek olmayan; başka bir şeye benzemesi için yapılmış","dt":"He was wearing a fake diamond ring.","e1":"Sahte bir elmas yüzük takıyordu.","e1t":"Is this signature fake?","e2":"Bu imza sahte mi?","e2t":""},{"w":"false","tr":"yanlış / sahte","te":"Adjective","tt":"Sıfat","de":"Not true or not natural","dt":"Doğru olmayan veya doğal olmayan","e1":"Is the statement true or false?","e1t":"İfade doğru mu yanlış mı?","e2":"He has false teeth.","e2t":"Takma (sahte) dişleri var."},{"w":"fame","tr":"ün / şöhret","te":"Noun","tt":"İsim","de":"The state of being known by many people","dt":"Birçok kişi tarafından tanınma durumu","e1":"He achieved fame at a young age.","e1t":"Genç yaşta şöhrete kavuştu.","e2":"Fame is not always a good thing.","e2t":"Şöhret her zaman iyi bir şey değildir."},{"w":"familiar","tr":"tanıdık","te":"Adjective","tt":"Sıfat","de":"Easy to recognize because seen before","dt":"Daha önce görüldüğü için tanınması kolay olan","e1":"His face looks familiar.","e1t":"Yüzü tanıdık geliyor.","e2":"Are you familiar with this software?","e2t":"Bu yazılıma aşina mısın (tanıyor musun)?"},{"w":"famous","tr":"ünlü","te":"Adjective","tt":"Sıfat","de":"Known by many people","dt":"Birçok kişi tarafından bilinen","e1":"Tarkan is a famous singer.","e1t":"Tarkan ünlü bir şarkıcıdır.","e2":"This city is famous for its history.","e2t":"Bu şehir tarihiyle ünlüdür."},{"w":"fan","tr":"hayran / yelpaze / vantilatör","te":"Noun","tt":"İsim","de":"A person who admires someone or a device for air","dt":"Birine hayran olan kişi veya hava cihazı","e1":"I am a big fan of rock music.","e1t":"Rock müziğin büyük bir hayranıyım.","e2":"Turn on the fan, it's very hot.","e2t":"Vantilatörü aç, hava çok sıcak."},{"w":"fancy","tr":"lüks / hayal etmek / istemek","te":"Adjective/Verb/Noun","tt":"Expensive, decorative or to want something","de":"Pahalı, süslü veya bir şeyi istemek","dt":"That’s a fancy restaurant.","e1":"Bu lüks bir restoran.","e1t":"Do you fancy a cup of tea?","e2":"Bir fincan çay ister misin (canın çekiyor mu)?","e2t":""},{"w":"fantastic","tr":"harika","te":"Adjective","tt":"Sıfat","de":"Extremely good or wonderful","dt":"Son derece iyi veya harika","e1":"You did a fantastic job.","e1t":"Harika bir iş çıkardın.","e2":"The weather was fantastic.","e2t":"Hava harikaydı."},{"w":"fantasy","tr":"fantezi / hayal","te":"Noun","tt":"İsim","de":"A situation that is imagined; not real","dt":"Hayal edilen durum; gerçek olmayan","e1":"He lives in a world of fantasy.","e1t":"Hayal dünyasında yaşıyor.","e2":"My favorite movie genre is fantasy.","e2t":"En sevdiğim film türü fantezidir."},{"w":"fare","tr":"bilet ücreti (yol)","te":"Noun","tt":"İsim","de":"The money paid for a journey on public transport","dt":"Toplu taşımada yolculuk için ödenen para","e1":"The bus fare has increased.","e1t":"Otobüs ücreti arttı.","e2":"How much is the train fare?","e2t":"Tren ücreti ne kadar?"},{"w":"farm","tr":"çiftlik","te":"Noun/Verb","tt":"İsim/Fiil","de":"Land used for growing crops or keeping animals","dt":"Mahsul yetiştirmek veya hayvan beslemek için kullanılan arazi","e1":"He grew up on a farm.","e1t":"Bir çiftlikte büyüdü.","e2":"They farm wheat in this region.","e2t":"Bu bölgede buğday tarımı (çiftçiliği) yapıyorlar."},{"w":"farming","tr":"çiftçilik / tarım","te":"Noun","tt":"İsim","de":"The activity of working on a farm","dt":"Çiftlikte çalışma faaliyeti","e1":"Farming is the main source of income here.","e1t":"Burada ana gelir kaynağı çiftçiliktir.","e2":"Organic farming is becoming popular.","e2t":"Organik tarım popülerleşiyor."},{"w":"fascinating","tr":"büyüleyici","te":"Adjective","tt":"Sıfat","de":"Extremely interesting","dt":"Son derece ilginç","e1":"I found the documentary fascinating.","e1t":"Belgeseli büyüleyici buldum.","e2":"Your life story is fascinating.","e2t":"Hayat hikayen büyüleyici."},{"w":"fashion","tr":"moda","te":"Noun","tt":"İsim","de":"A popular style of clothes or hair","dt":"Popüler kıyafet veya saç stili","e1":"She is interested in fashion.","e1t":"Modayla ilgileniyor.","e2":"These shoes are out of fashion.","e2t":"Bu ayakkabıların modası geçti."},{"w":"fashionable","tr":"moda olan / şık","te":"Adjective","tt":"Sıfat","de":"Popular at a particular time","dt":"Belirli bir zamanda popüler olan","e1":"It’s a very fashionable dress.","e1t":"Çok moda (şık) bir elbise.","e2":"This neighborhood has become very fashionable.","e2t":"Bu mahalle çok popülerleşti."},{"w":"fasten","tr":"bağlamak","te":"Verb","tt":"Fiil","de":"To close or join something firmly","dt":"Bir şeyi sıkıca kapatmak veya birleştirmek","e1":"Fasten your seat belt, please.","e1t":"Lütfen emniyet kemerinizi bağlayın.","e2":"Can you help me fasten this?","e2t":"Bunu bağlamama yardım edebilir misin?"},{"w":"fat","tr":"kilolu / yağ","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having a lot of flesh or an oily substance","dt":"Çok eti olan veya yağlı madde","e1":"Don't eat too much fat.","e1t":"Çok fazla yağ yeme.","e2":"He is getting a bit fat.","e2t":"Biraz kilo alıyor (şişmanlıyor)."},{"w":"fatal","tr":"ölümcül","te":"Adjective","tt":"Sıfat","de":"Causing death","dt":"Ölüme sebep olan","e1":"It was a fatal accident.","e1t":"Ölümcül bir kazaydı.","e2":"He made a fatal mistake.","e2t":"Ölümcül (vahim) bir hata yaptı."},{"w":"fate","tr":"kader","te":"Noun","tt":"İsim","de":"A power that is believed to control what happens","dt":"Olanları kontrol ettiğine inanılan güç","e1":"It was fate that we met.","e1t":"Tanışmamız kaderdi.","e2":"You cannot escape your fate.","e2t":"Kaderinden kaçamazsın."},{"w":"fault","tr":"hata","te":"Noun","tt":"İsim","de":"A mistake or responsibility for something wrong","dt":"Bir yanlış veya yanlış bir şeyin sorumluluğu","e1":"It's not my fault!","e1t":"Bu benim hatam değil!","e2":"There is a fault in the electrical system.","e2t":"Elektrik sisteminde bir hata (arıza) var."},{"w":"favor / favour","tr":"iyilik / taraf tutmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A kind action or to support someone","dt":"Nazik bir eylem veya birini desteklemek","e1":"Can you do me a favor?","e1t":"Bana bir iyilik yapabilir misin?","e2":"I am in favor of the new plan.","e2t":"Yeni planın tarafındayım (destekliyorum)."},{"w":"favorable","tr":"olumlu / elverişli","te":"Adjective","tt":"Sıfat","de":"Showing approval or being helpful","dt":"Onay gösteren veya yardımcı olan","e1":"We received a favorable response.","e1t":"Olumlu bir yanıt aldık.","e2":"The weather conditions were favorable for sailing.","e2t":"Hava koşulları yelken açmak için elverişliydi."},{"w":"favorite / favourite","tr":"en sevilen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Liked more than others","dt":"Diğerlerinden daha çok sevilen","e1":"Blue is my favorite color.","e1t":"Mavi en sevdiğim renktir.","e2":"Who is your favorite actor?","e2t":"En sevdiğin oyuncu kim?"},{"w":"fear","tr":"korku","te":"Noun/Verb","tt":"İsim/Fiil","de":"An unpleasant emotion caused by danger","dt":"Tehlikenin neden olduğu hoş olmayan duygu","e1":"He has a fear of heights.","e1t":"Yükseklik korkusu var.","e2":"There is nothing to fear.","e2t":"Korkacak bir şey yok."},{"w":"fearful","tr":"korku dolu / korkunç","te":"Adjective","tt":"Sıfat","de":"Afraid or causing fear","dt":"Korkmuş veya korkuya neden olan","e1":"She looked fearful.","e1t":"Korku dolu görünüyordu.","e2":"It was a fearful sight.","e2t":"Korkunç bir manzaraydı."},{"w":"feather","tr":"tüy","te":"Noun","tt":"İsim","de":"One of the soft things that cover a bird","dt":"Kuşu örten yumuşak şeylerden her biri","e1":"As light as a feather.","e1t":"Tüy kadar hafif.","e2":"The bird is cleaning its feathers.","e2t":"Kuş tüylerini temizliyor."},{"w":"feature","tr":"özellik","te":"Noun","tt":"İsim","de":"An important part or characteristic","dt":"Önemli bir parça veya karakteristik","e1":"This phone has many new features.","e1t":"Bu telefonun birçok yeni özelliği var.","e2":"The lake is the main feature of the park.","e2t":"Göl, parkın ana özelliğidir."},{"w":"federal","tr":"federal","te":"Adjective","tt":"Sıfat","de":"Relating to a central government","dt":"Merkezi bir hükümetle ilgili","e1":"The FBI is a federal agency.","e1t":"FBI federal bir ajanstır.","e2":"They follow federal laws.","e2t":"Federal yasalara uyuyorlar."},{"w":"fee","tr":"ücret","te":"Noun","tt":"İsim","de":"An amount of money paid for a service","dt":"Bir hizmet için ödenen para miktarı","e1":"What is the entrance fee?","e1t":"Giriş ücreti nedir?","e2":"You have to pay a tuition fee.","e2t":"Okul ücreti ödemeniz gerekiyor."},{"w":"feed","tr":"beslemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give food to a person or animal","dt":"Bir kişiye veya hayvana yemek vermek","e1":"Don't forget to feed the cat.","e1t":"Kediyi beslemeyi unutma.","e2":"What do you feed your dog?","e2t":"Köpeğini neyle besliyorsun?"},{"w":"feedback","tr":"geri bildirim","te":"Noun","tt":"İsim","de":"Information about a person's performance","dt":"Bir kişinin performansı hakkında bilgi","e1":"Thank you for your feedback.","e1t":"Geri bildiriminiz için teşekkürler.","e2":"Positive feedback is encouraging.","e2t":"Olumlu geri bildirim yüreklendiricidir."},{"w":"feeling","tr":"his","te":"Noun","tt":"İsim","de":"An emotional state or a physical sensation","dt":"Duygusal bir durum veya fiziksel bir duyum","e1":"I have a feeling that something is wrong.","e1t":"Bir şeylerin yanlış olduğuna dair bir hissim var.","e2":"He hurt my feelings.","e2t":"Duygularımı incitti (beni kırdı)."},{"w":"fellow","tr":"dost / arkadaş / adam","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A man or someone in the same position","dt":"Bir adam veya aynı konumdaki biri","e1":"He is a nice young fellow.","e1t":"O hoş bir genç adam.","e2":"I want to help my fellow citizens.","e2t":"Vatandaş dostlarıma (hemşehrilerime) yardım etmek istiyorum."},{"w":"female","tr":"kadın (cinsiyet)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Belonging to the sex that can give birth","dt":"Doğum yapabilen cinsiyete ait olan","e1":"We have more female students than male.","e1t":"Erkeklerden daha fazla kadın öğrencimiz var.","e2":"The female lion is the hunter.","e2t":"Dişi aslan avcıdır."},{"w":"fence","tr":"çit","te":"Noun/Verb","tt":"İsim/Fiil","de":"A structure that surrounds an area","dt":"Bir alanı çevreleyen yapı","e1":"He painted the garden fence.","e1t":"Bahçe çitini boyadı.","e2":"The dog jumped over the fence.","e2t":"Köpek çitin üzerinden atladı."},{"w":"festival","tr":"festival","te":"Noun","tt":"İsim","de":"A series of special events or performances","dt":"Bir dizi özel etkinlik veya performans","e1":"The jazz festival starts tomorrow.","e1t":"Caz festivali yarın başlıyor.","e2":"We attended a local food festival.","e2t":"Yerel bir yemek festivaline katıldık."},{"w":"fever","tr":"ateş (hastalık)","te":"Noun","tt":"İsim","de":"A high body temperature","dt":"Yüksek vücut ısısı","e1":"He has a high fever.","e1t":"Yüksek ateşi var.","e2":"The baby has a slight fever.","e2t":"Bebeğin hafif ateşi var."},{"w":"fiber / fibre","tr":"lif / elyaf","te":"Noun","tt":"İsim","de":"A thin thread or a substance in food","dt":"İnce bir ip veya gıdadaki madde","e1":"Fruits are rich in fiber.","e1t":"Meyveler lif açısından zengindir.","e2":"Optical fiber is used for high","e2t":"speed internet."},{"w":"fiction","tr":"kurgu","te":"Noun","tt":"İsim","de":"Stories about imaginary people and events","dt":"Hayali insanlar ve olaylar hakkındaki hikayeler","e1":"I prefer reading fiction to non","e1t":"fiction.","e2":"Kurguyu kurgu dışına tercih ederim.","e2t":"Science fiction is a popular genre."},{"w":"field","tr":"alan","te":"Noun","tt":"İsim","de":"An area of land or a subject of study","dt":"Bir arazi parçası veya bir çalışma konusu","e1":"The cows are in the field.","e1t":"İnekler tarlada (alanda).","e2":"He is an expert in the field of medicine.","e2t":"Tıp alanında bir uzmandır."},{"w":"fifteen","tr":"on beş","te":"Number","tt":"Sayı","de":"The number 15","dt":"15 sayısı","e1":"He is fifteen years old.","e1t":"O on beş yaşında.","e2":"The match starts in fifteen minutes.","e2t":"Maç on beş dakika içinde başlıyor."},{"w":"fifth","tr":"beşinci","te":"Number/Adjective","tt":"The position of number five","de":"Beşinci sıra","dt":"Today is the fifth of May.","e1":"Bugün Mayıs'ın beşi (beşincisi).","e1t":"He finished the race in fifth place.","e2":"Yarışı beşinci sırada bitirdi.","e2t":""},{"w":"fifty","tr":"elli","te":"Number","tt":"Sayı","de":"The number 50","dt":"50 sayısı","e1":"My father is fifty years old.","e1t":"Babam elli yaşında.","e2":"There are fifty states in the USA.","e2t":"ABD'de elli eyalet vardır."},{"w":"fight","tr":"kavga / savaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To use physical force or to struggle","dt":"Fiziksel güç kullanmak veya mücadele etmek","e1":"Don't fight with your brother.","e1t":"Erkek kardeşinle kavga etme.","e2":"They are fighting for their rights.","e2t":"Hakları için savaşıyorlar."},{"w":"fighter","tr":"savaşçı / dövüşçü","te":"Noun","tt":"İsim","de":"A person who fights","dt":"Savaşan kişi","e1":"He is a brave fighter.","e1t":"O cesur bir savaşçıdır.","e2":"The fire fighters arrived quickly.","e2t":"İtfaiyeciler (ateş savaşçıları) hızla geldi."},{"w":"figure","tr":"rakam / şekil","te":"Noun","tt":"İsim","de":"A number or the shape of a person's body","dt":"Bir sayı veya bir kişinin vücut şekli","e1":"Write the figure in words.","e1t":"Rakamı yazıyla yaz.","e2":"She has a slim figure.","e2t":"İnce bir fiziği (şekli) var."},{"w":"file","tr":"dosya","te":"Noun/Verb","tt":"İsim/Fiil","de":"A folder for keeping papers or digital data","dt":"Kağıtları veya dijital verileri saklamak için klasör","e1":"I can't open this file.","e1t":"Bu dosyayı açamıyorum.","e2":"Keep these papers in a file.","e2t":"Bu kağıtları bir dosyada sakla."},{"w":"fill","tr":"doldurmak","te":"Verb","tt":"Fiil","de":"To make something full","dt":"Bir şeyi tam/dolu hale getirmek","e1":"Fill the glass with water.","e1t":"Bardağı suyla doldur.","e2":"Please fill in the application form.","e2t":"Lütfen başvuru formunu doldurun."},{"w":"final","tr":"final","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Last or coming at the end","dt":"Sonuncu veya sonda gelen","e1":"This is my final decision.","e1t":"Bu benim son kararım.","e2":"Who won the tennis final?","e2t":"Tenis finalini kim kazandı?"},{"w":"finally","tr":"sonunda","te":"Adverb","tt":"Zarf","de":"After a long time or at the end","dt":"Uzun bir süre sonra veya sonunda","e1":"Finally, the bus arrived.","e1t":"Sonunda otobüs geldi.","e2":"I have finally finished my project.","e2t":"Projemi sonunda bitirdim."},{"w":"finance","tr":"finans","te":"Noun/Verb","tt":"İsim/Fiil","de":"The management of large amounts of money","dt":"Büyük miktardaki paranın yönetimi","e1":"He is studying international finance.","e1t":"Uluslararası finans okuyor.","e2":"How will you finance your project?","e2t":"Projeni nasıl finanse edeceksin?"},{"w":"financial","tr":"finansal / mali","te":"Adjective","tt":"Sıfat","de":"Relating to money","dt":"Para ile ilgili","e1":"The company is in financial trouble.","e1t":"Şirket mali sıkıntıda.","e2":"I need some financial advice.","e2t":"Biraz finansal tavsiyeye ihtiyacım var."},{"w":"find","tr":"bulmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To discover something or someone","dt":"Bir şeyi veya birini keşfetmek","e1":"I can't find my keys.","e1t":"Anahtarlarımı bulamıyorum.","e2":"It was a great find!","e2t":"Harika bir buluştu!"},{"w":"finding","tr":"bulgu","te":"Noun","tt":"İsim","de":"A piece of information discovered after research","dt":"Araştırma sonrası keşfedilen bilgi","e1":"The findings of the report are interesting.","e1t":"Raporun bulguları ilginç.","e2":"We must share our findings with the team.","e2t":"Bulgularımızı ekiple paylaşmalıyız."},{"w":"fine","tr":"iyi / ince / para cezası","te":"Adjective/Noun/Verb","tt":"Good, thin, or a penalty fee","de":"İyi, ince veya ceza ödemesi","dt":"I'm fine, thank you.","e1":"İyiyim, teşekkür ederim.","e1t":"He had to pay a fine for speeding.","e2":"Hız yaptığı için para cezası ödemek zorunda kaldı.","e2t":""},{"w":"fireman / firefighter","tr":"itfaiyeci","te":"Noun","tt":"İsim","de":"A person whose job is to put out fires","dt":"İşi yangın söndürmek olan kişi","e1":"The firemen arrived in five minutes.","e1t":"İtfaiyeciler beş dakika içinde geldi.","e2":"He wants to be a firefighter.","e2t":"İtfaiyeci olmak istiyor."},{"w":"firm","tr":"firma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A business company or solid/hard","dt":"Bir ticari şirket veya sert/katı","e1":"He works for a law firm.","e1t":"Bir hukuk firmasında çalışıyor.","e2":"You need a firm bed for your back.","e2t":"Sırtın için sert bir yatağa ihtiyacın var."},{"w":"firmly","tr":"sıkıca / kararlılıkla","te":"Adverb","tt":"Zarf","de":"In a strong or steady way","dt":"Güçlü veya istikrarlı bir şekilde","e1":"Hold the handle firmly.","e1t":"Kolu sıkıca tut.","e2":"He firmly believes in his theory.","e2t":"Teorisine kararlılıkla inanıyor."},{"w":"fisherman","tr":"balıkçı","te":"Noun","tt":"İsim","de":"A person who catches fish","dt":"Balık tutan kişi","e1":"The old fisherman caught a big tuna.","e1t":"Yaşlı balıkçı büyük bir ton balığı yakaladı.","e2":"Many fishermen work in this village.","e2t":"Bu köyde birçok balıkçı çalışıyor."},{"w":"fishing","tr":"balık tutma","te":"Noun","tt":"İsim","de":"The activity of catching fish","dt":"Balık yakalama faaliyeti","e1":"Fishing is his favorite hobby.","e1t":"Balık tutmak onun en sevdiği hobisidir.","e2":"We went fishing last weekend.","e2t":"Geçen hafta sonu balık tutmaya gittik."},{"w":"fit","tr":"uygun / formda / uymak","te":"Adjective/Verb","tt":"Healthy or the right size","de":"Sağlıklı veya doğru beden","dt":"I go to the gym to keep fit.","e1":"Formda kalmak için spor salonuna giderim.","e1t":"These shoes don't fit me.","e2":"Bu ayakkabılar bana olmuyor (uymuyor).","e2t":""},{"w":"fitness","tr":"formda olma","te":"Noun","tt":"İsim","de":"Being physically healthy and strong","dt":"Fiziksel olarak sağlıklı ve güçlü olma","e1":"Physical fitness is important for everyone.","e1t":"Fiziksel formda olmak herkes için önemlidir.","e2":"I go to the fitness center twice a week.","e2t":"Haftada iki kez spor (fitness) merkezine giderim."},{"w":"five","tr":"beş","te":"Number","tt":"Sayı","de":"The number 5","dt":"5 sayısı","e1":"I have five fingers on each hand.","e1t":"Her elimde beş parmak var.","e2":"The meeting is at five o'clock.","e2t":"Toplantı saat beşte."},{"w":"fix","tr":"tamir etmek","te":"Verb","tt":"Fiil","de":"To repair something that is broken","dt":"Bozuk olan bir şeyi onarmak","e1":"Can you fix my computer?","e1t":"Bilgisayarımı tamir edebilir misin?","e2":"I need to fix this problem.","e2t":"Bu sorunu çözmem (düzeltmem) gerekiyor."},{"w":"fixed","tr":"sabit","te":"Adjective","tt":"Sıfat","de":"Fastened or staying the same","dt":"Sabitlenmiş veya aynı kalan","e1":"The price is fixed.","e1t":"Fiyat sabittir.","e2":"He has a fixed routine.","e2t":"Sabit (değişmez) bir rutini var."},{"w":"flag","tr":"bayrak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of cloth with a special design","dt":"Özel tasarımlı kumaş parçası","e1":"The Turkish flag is red and white.","e1t":"Türk bayrağı kırmızı beyazdır.","e2":"They raised the flag at sunrise.","e2t":"Gün doğumunda bayrağı çektiler."},{"w":"flame","tr":"alev","te":"Noun/Verb","tt":"İsim/Fiil","de":"A hot bright stream of burning gas","dt":"Yanmakta olan gazın sıcak parlak akışı","e1":"The candle flame flickered.","e1t":"Mum alevi titredi.","e2":"The house was in flames.","e2t":"Ev alevler içindeydi."},{"w":"flash","tr":"flaş / parlamak / ani","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden bright light or to shine","dt":"Ani parlak ışık veya parlamak","e1":"Don't use flash in the museum.","e1t":"Müzede flaş kullanmayın.","e2":"A flash of lightning lit up the sky.","e2t":"Bir şimşek çakışı gökyüzünü aydınlattı."},{"w":"flat","tr":"daire (ev)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A set of rooms for living in or a level surface","dt":"Yaşamak için odalar seti veya düz bir yüzey","e1":"They live in a flat on the second floor.","e1t":"İkinci katta bir dairede yaşıyorlar.","e2":"The earth is not flat.","e2t":"Dünya düz değildir."},{"w":"flavor / flavour","tr":"lezzet / aroma","te":"Noun/Verb","tt":"İsim/Fiil","de":"The taste of food or drink","dt":"Yiyecek veya içeceğin tadı","e1":"I like the flavor of chocolate.","e1t":"Çikolata aromasını severim.","e2":"They added spice to flavor the meat.","e2t":"Eti lezzetlendirmek için baharat eklediler."},{"w":"flee","tr":"kaçmak (tehlikeden)","te":"Verb","tt":"Fiil","de":"To run away from a place or danger","dt":"Bir yerden veya tehlikeden kaçmak","e1":"Thousands of people fled the war.","e1t":"Binlerce kişi savaştan kaçtı.","e2":"The thief fled when he saw the police.","e2t":"Hırsız polisi görünce kaçtı."},{"w":"flesh","tr":"et (canlı)","te":"Noun","tt":"İsim","de":"The soft part of a body or fruit","dt":"Vücudun veya meyvenin yumuşak kısmı","e1":"The spirit is willing, but the flesh is weak.","e1t":"Ruh istekli ama beden (et) zayıf.","e2":"The apple has sweet white flesh.","e2t":"Elmanın tatlı beyaz bir eti (içi) var."},{"w":"flexible","tr":"esnek","te":"Adjective","tt":"Sıfat","de":"Able to bend easily or change","dt":"Kolayca bükülebilen veya değişebilen","e1":"Rubber is a flexible material.","e1t":"Kauçuk esnek bir malzemedir.","e2":"My work hours are flexible.","e2t":"Çalışma saatlerim esnektir."},{"w":"flight","tr":"uçuş","te":"Noun","tt":"İsim","de":"A journey in an aircraft","dt":"Hava taşıtı ile yapılan yolculuk","e1":"How was your flight?","e1t":"Uçuşun nasıldı?","e2":"The flight was delayed for two hours.","e2t":"Uçuş iki saat gecikti."},{"w":"float","tr":"batmadan yüzmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stay on the surface of a liquid","dt":"Bir sıvının yüzeyinde kalmak","e1":"Wood floats on water.","e1t":"Odun suyun üzerinde yüzer (batmaz).","e2":"A balloon floated in the air.","e2t":"Havada bir balon süzüldü."},{"w":"flood","tr":"sel","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large amount of water covering an area","dt":"Bir alanı kaplayan büyük miktarda su","e1":"The heavy rain caused a flood.","e1t":"Şiddetli yağmur sele neden oldu.","e2":"The kitchen floor was flooded.","e2t":"Mutfak zeminini su bastı."},{"w":"flour","tr":"un","te":"Noun","tt":"İsim","de":"Powder made from grain used for baking","dt":"Pişirme için kullanılan tahıl tozu","e1":"We need flour to make bread.","e1t":"Ekmek yapmak için una ihtiyacımız var.","e2":"Mix the flour and eggs.","e2t":"Unu ve yumurtaları karıştırın."},{"w":"flow","tr":"akış / akmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move steadily like a liquid","dt":"Bir sıvı gibi istikrarlı hareket etmek","e1":"The river flows into the sea.","e1t":"Nehir denize akar.","e2":"The flow of traffic is slow today.","e2t":"Trafik akışı bugün yavaş."},{"w":"flower","tr":"çiçek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The colorful part of a plant","dt":"Bitkinin renkli kısmı","e1":"Rose is a beautiful flower.","e1t":"Gül güzel bir çiçektir.","e2":"The plants are starting to flower.","e2t":"Bitkiler çiçek açmaya başlıyor."},{"w":"flu / influenza","tr":"grip","te":"Noun","tt":"İsim","de":"A common infectious disease","dt":"Yaygın bulaşıcı bir hastalık","e1":"I have the flu and a fever.","e1t":"Gribim ve ateşim var.","e2":"You should stay at home if you have the flu.","e2t":"Gribin varsa evde kalmalısın."},{"w":"fluid","tr":"sıvı / akışkan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance that flows like water","dt":"Su gibi akan madde","e1":"Drink plenty of fluids.","e1t":"Bol sıvı tüketin.","e2":"The situation is very fluid (changing).","e2t":"Durum çok değişken (akışkan)."},{"w":"fly","tr":"uçmak / sinek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move through the air or a small insect","dt":"Havada hareket etmek veya küçük böcek","e1":"Birds can fly.","e1t":"Kuşlar uçabilir.","e2":"There is a fly in my soup!","e2t":"Çorbamda bir sinek var!"},{"w":"focus","tr":"odaklanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give all your attention to something","dt":"Tüm dikkatinizi bir şeye vermek","e1":"Focus on the most important tasks.","e1t":"En önemli görevlere odaklan.","e2":"The main focus of the meeting was sales.","e2t":"Toplantının ana odağı satışlardı."},{"w":"fog","tr":"sis","te":"Noun/Verb","tt":"İsim/Fiil","de":"Thick clouds close to the ground","dt":"Yere yakın yoğun bulutlar","e1":"I can't see the road because of the fog.","e1t":"Sis yüzünden yolu göremiyorum.","e2":"The windows fogged up.","e2t":"Camlar buğulandı (sis gibi kapandı)."},{"w":"fold","tr":"katlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To bend something so one part covers another","dt":"Bir şeyi bir parçası diğerini örtecek şekilde bükmek","e1":"Fold the paper in half.","e1t":"Kağıdı ikiye katla.","e2":"He folded his arms.","e2t":"Kollarını kavuşturdu (katladı)."},{"w":"folk","tr":"halk","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"People in general or traditional culture","dt":"Genel olarak insanlar veya geleneksel kültür","e1":"I like Turkish folk music.","e1t":"Türk halk müziğini severim.","e2":"Some folk believe in ghosts.","e2t":"Bazı insanlar (halk) hayaletlere inanır."},{"w":"follow","tr":"takip etmek","te":"Verb","tt":"Fiil","de":"To go behind someone or obey rules","dt":"Birinin arkasından gitmek veya kurallara uymak","e1":"Follow the signs to the exit.","e1t":"Çıkış için işaretleri takip et.","e2":"I follow him on social media.","e2t":"Onu sosyal medyada takip ediyorum."},{"w":"following","tr":"takip eden / aşağıdaki","te":"Adjective/Preposition/Noun","tt":"Coming after or next","de":"Sonra gelen veya sıradaki","dt":"Read the following sentences.","e1":"Aşağıdaki cümleleri okuyun.","e1t":"Following the meeting, we had lunch.","e2":"Toplantının ardından öğle yemeği yedik.","e2t":""},{"w":"fond","tr":"düşkün / seven","te":"Adjective","tt":"Sıfat","de":"Having a liking for someone or something","dt":"Birini veya bir şeyi sevme/ona düşkün olma","e1":"I am very fond of animals.","e1t":"Hayvanlara çok düşkünüm (severim).","e2":"He has fond memories of his childhood.","e2t":"Çocukluğuna dair sevgi dolu (güzel) anıları var."},{"w":"fool","tr":"aptal / kandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who lacks sense or to trick someone","dt":"Mantığı olmayan kişi veya birini kandırmak","e1":"Don't be a fool!","e1t":"Aptal olma!","e2":"You can't fool me!","e2t":"Beni kandıramazsın!"},{"w":"forbid","tr":"yasaklamak","te":"Verb","tt":"Fiil","de":"To order someone not to do something","dt":"Birine bir şeyi yapmamasını emretmek","e1":"My doctor forbade me to smoke.","e1t":"Doktorum bana sigara içmeyi yasakladı.","e2":"Photography is forbidden in the museum.","e2t":"Müzede fotoğraf çekmek yasaktır."},{"w":"force","tr":"güç / zorlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Physical power or to make someone do something","dt":"Fiziksel güç veya birini bir şeye zorlamak","e1":"They used force to open the door.","e1t":"Kapıyı açmak için güç kullandılar.","e2":"You can't force him to stay.","e2t":"Onu kalmaya zorlayamazsın."},{"w":"forecast","tr":"tahmin (hava vb.)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A statement of what is likely to happen","dt":"Ne olacağına dair yapılan tahmin","e1":"What is the weather forecast for tomorrow?","e1t":"Yarın için hava durumu tahmini nedir?","e2":"They forecast a rise in prices.","e2t":"Fiyatlarda bir artış tahmin ediyorlar."},{"w":"foreign","tr":"yabancı","te":"Adjective","tt":"Sıfat","de":"From another country","dt":"Başka bir ülkeden olan","e1":"I like learning foreign languages.","e1t":"Yabancı diller öğrenmeyi severim.","e2":"She has many foreign friends.","e2t":"Onun birçok yabancı arkadaşı var."},{"w":"foreigner","tr":"yabancı (kişi)","te":"Noun","tt":"İsim","de":"A person from another country","dt":"Başka bir ülkeden olan kişi","e1":"There are many foreigners in Istanbul.","e1t":"İstanbul'da birçok yabancı var.","e2":"He is a foreigner here.","e2t":"O burada bir yabancıdır."},{"w":"forever","tr":"sonsuza dek","te":"Adverb","tt":"Zarf","de":"For all time","dt":"Tüm zamanlar boyunca","e1":"I will love you forever.","e1t":"Seni sonsuza dek seveceğim.","e2":"Nothing lasts forever.","e2t":"Hiçbir şey sonsuza dek sürmez."},{"w":"forgive","tr":"affetmek","te":"Verb","tt":"Fiil","de":"To stop being angry with someone","dt":"Biriyle kızgın olmayı bırakmak","e1":"Please forgive me for being late.","e1t":"Geç kaldığım için lütfen beni affet.","e2":"It's hard to forgive him.","e2t":"Onu affetmek zor."},{"w":"form","tr":"form / şekil","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of something or a document to fill","dt":"Bir şeyin türü veya doldurulacak bir belge","e1":"Ice is a form of water.","e1t":"Buz suyun bir formudur (şeklidir).","e2":"Please sign the form.","e2t":"Lütfen formu imzalayın."},{"w":"formal","tr":"resmi","te":"Adjective","tt":"Sıfat","de":"Following official rules or dress codes","dt":"Resmi kurallara veya kıyafet kodlarına uyan","e1":"He wore a formal suit to the wedding.","e1t":"Düğüne resmi bir takım elbise giydi.","e2":"The meeting was very formal.","e2t":"Toplantı çok resmiydi."},{"w":"format","tr":"format / biçim","te":"Noun/Verb","tt":"İsim/Fiil","de":"The arrangement or plan of something","dt":"Bir şeyin düzeni veya planı","e1":"What is the format of the exam?","e1t":"Sınavın formatı (biçimi) nedir?","e2":"I need to format my hard drive.","e2t":"Sabit sürücümü formatlamam (biçimlendirmem) gerekiyor."},{"w":"formation","tr":"oluşum","te":"Noun","tt":"İsim","de":"The act of forming something","dt":"Bir şeyi oluşturma eylemi","e1":"The formation of a new government took weeks.","e1t":"Yeni bir hükümetin kurulması (oluşumu) haftalar sürdü.","e2":"Look at the rock formations.","e2t":"Kaya oluşumlarına bak."},{"w":"former","tr":"önceki","te":"Adjective","tt":"Sıfat","de":"Happening or existing in the past","dt":"Geçmişte olan veya var olan","e1":"He is a former president.","e1t":"O eski (önceki) bir başkandır.","e2":"In former times, people traveled by horse.","e2t":"Eski zamanlarda insanlar atla seyahat ederdi."},{"w":"formerly","tr":"eskiden","te":"Adverb","tt":"Zarf","de":"In the past","dt":"Geçmişte","e1":"Istanbul was formerly known as Constantinople.","e1t":"İstanbul eskiden Konstantinopolis olarak bilinirdi.","e2":"He formerly worked for a bank.","e2t":"Eskiden bir bankada çalışıyordu."},{"w":"formula","tr":"formül","te":"Noun","tt":"İsim","de":"A mathematical rule or a set of instructions","dt":"Matematiksel kural veya talimatlar seti","e1":"What is the formula for water? ()","e1t":"Suyun formülü nedir? ()","e2":"I am looking for a successful business formula.","e2t":"Başarılı bir iş formülü arıyorum."},{"w":"forth","tr":"ileriye doğru","te":"Adverb","tt":"Zarf","de":"Out or forward","dt":"Dışarı veya ileriye doğru","e1":"He walked back and forth.","e1t":"İleri geri yürüdü.","e2":"From that day forth, everything changed.","e2t":"O günden itibaren her şey değişti."},{"w":"fortune","tr":"servet / talih","te":"Noun","tt":"İsim","de":"A large amount of money or luck","dt":"Büyük miktarda para veya şans","e1":"He made a fortune in real estate.","e1t":"Emlak işinden bir servet kazandı.","e2":"Good fortune attended his efforts.","e2t":"Çabalarına iyi talih eşlik etti."},{"w":"forty","tr":"kırk","te":"Number","tt":"Sayı","de":"The number 40","dt":"40 sayısı","e1":"My brother is forty years old.","e1t":"Erkek kardeşim kırk yaşında.","e2":"The bus leaves in forty minutes.","e2t":"Otobüs kırk dakika içinde kalkıyor."},{"w":"forward","tr":"ileri","te":"Adverb/Adjective","tt":"Towards the front or the future","de":"Öne veya geleceğe doğru","dt":"Take one step forward.","e1":"Bir adım ileri at.","e1t":"I am looking forward to seeing you.","e2":"Seni görmeyi dört gözle bekliyorum (ileriye bakıyorum).","e2t":""},{"w":"found","tr":"kurmak","te":"Verb","tt":"Fiil","de":"To start an organization or institution","dt":"Bir organizasyon veya kurum başlatmak","e1":"He founded the company in 2010.","e1t":"Şirketi 2010 yılında kurdu.","e2":"The city was founded by the Romans.","e2t":"Şehir Romalılar tarafından kuruldu."},{"w":"foundation","tr":"vakıf / temel","te":"Noun","tt":"Isim","de":"An organization or the base of a building","dt":"Bir kuruluş veya bir binanın temeli","e1":"He donated money to a charity foundation.","e1t":"Bir hayır vakfına para bağışladı.","e2":"The house needs a strong foundation.","e2t":"Evin güçlü bir temele ihtiyacı var."},{"w":"founder","tr":"kurucu","te":"Noun","tt":"İsim","de":"A person who starts an organization","dt":"Bir organizasyonu başlatan kişi","e1":"He is the founder of the company.","e1t":"O, şirketin kurucusudur.","e2":"Ataturk is the founder of the Republic.","e2t":"Atatürk, Cumhuriyet'in kurucusudur."},{"w":"fountain","tr":"fıskiye / çeşme","te":"Noun","tt":"İsim","de":"A structure that sends water into the air","dt":"Havaya su püskürten yapı","e1":"There is a beautiful fountain in the park.","e1t":"Parkta güzel bir fıskiye var.","e2":"I drank water from the fountain.","e2t":"Çeşmeden su içtim."},{"w":"four","tr":"dört","te":"Number","tt":"Sayı","de":"The number 4","dt":"4 sayısı","e1":"A square has four sides.","e1t":"Bir karenin dört kenarı vardır.","e2":"I have four cats.","e2t":"Dört kedim var."},{"w":"fourteen","tr":"on dört","te":"Number","tt":"Sayı","de":"The number 14","dt":"14 sayısı","e1":"He is fourteen years old.","e1t":"O on dört yaşında.","e2":"There are fourteen days in two weeks.","e2t":"İki haftada on dört gün vardır."},{"w":"fourth","tr":"dördüncü","te":"Number/Adjective","tt":"The position of number four","de":"Dördüncü sıra","dt":"My office is on the fourth floor.","e1":"Ofisim dördüncü katta.","e1t":"This is the fourth time I've called you.","e2":"Bu seni dördüncü arayışım.","e2t":""},{"w":"fox","tr":"tilki","te":"Noun","tt":"İsim","de":"A wild animal like a dog with a thick tail","dt":"Kalın kuyruklu, köpeğe benzeyen vahşi hayvan","e1":"The fox is very smart.","e1t":"Tilki çok zekidir.","e2":"Red fox.","e2t":"Kızıl tilki."},{"w":"frame","tr":"çerçeve","te":"Noun/Verb","tt":"İsim/Fiil","de":"A border around a picture or window","dt":"Bir resim veya pencere etrafındaki kenarlık","e1":"I bought a new frame for the photo.","e1t":"Fotoğraf için yeni bir çerçeve aldım.","e2":"The window frame is made of wood.","e2t":"Pencere çerçevesi ahşaptan yapılmış."},{"w":"framework","tr":"çerçeve / yapı","te":"Noun","tt":"İsim","de":"A supporting structure or a system of rules","dt":"Destekleyici yapı veya kurallar sistemi","e1":"We need a legal framework for this.","e1t":"Bunun için yasal bir çerçeveye ihtiyacımız var.","e2":"The framework of the building is steel.","e2t":"Binanın iskeleti (yapısı) çeliktir."},{"w":"frankly","tr":"dürüstçe","te":"Adverb","tt":"Zarf","de":"In an honest and direct way","dt":"Dürüst ve doğrudan bir yolla","e1":"Frankly, I don't care.","e1t":"Dürüst olmak gerekirse, umrumda değil.","e2":"He spoke frankly about his problems.","e2t":"Sorunları hakkında dürüstçe konuştu."},{"w":"free","tr":"özgür / ücretsiz","te":"Adjective/Adverb/Verb","tt":"Not restricted or costing nothing","de":"Kısıtlanmamış veya maliyeti olmayan","dt":"You are free to go.","e1":"Gitmekte özgürsün.","e1t":"The water is free of charge.","e2":"Su ücretsizdir.","e2t":""},{"w":"freedom","tr":"özgürlük","te":"Noun","tt":"İsim","de":"The state of being free","dt":"Özgür olma durumu","e1":"Freedom of speech is important.","e1t":"İfade özgürlüğü önemlidir.","e2":"He fought for the freedom of his country.","e2t":"Ülkesinin özgürlüğü için savaştı."},{"w":"freely","tr":"özgürce","te":"Adverb","tt":"Zarf","de":"In a free way; without control","dt":"Özgür bir yolla; kontrolsüzce","e1":"You can speak freely here.","e1t":"Burada özgürce konuşabilirsin.","e2":"Information flows freely on the internet.","e2t":"Bilgi internette özgürce akar."},{"w":"freeze","tr":"donmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become hard because of cold","dt":"Soğuk nedeniyle sertleşmek","e1":"The lake froze last night.","e1t":"Göl dün gece dondu.","e2":"Freeze the meat to keep it fresh.","e2t":"Taze kalması için eti dondur."},{"w":"freezer","tr":"dondurucu","te":"Noun","tt":"İsim","de":"A machine used to keep food frozen","dt":"Yiyecekleri donmuş halde tutmak için kullanılan makine","e1":"Put the ice cream in the freezer.","e1t":"Dondurmayı dondurucuya koy.","e2":"Is there any ice in the freezer?","e2t":"Dondurucuda hiç buz var mı?"},{"w":"frequent","tr":"sık / yaygın","te":"Adjective/Verb","tt":"Happening often","de":"Sık sık olan","dt":"He is a frequent visitor to this cafe.","e1":"Bu kafenin sık bir ziyaretçisidir.","e1t":"Rain is frequent in this region.","e2":"Bu bölgede yağmur yaygındır (sıktır).","e2t":""},{"w":"frequently","tr":"sık sık","te":"Adverb","tt":"Zarf","de":"Often","dt":"Sık sık","e1":"I frequently go to the cinema.","e1t":"Sık sık sinemaya giderim.","e2":"This problem happens frequently.","e2t":"Bu sorun sık sık yaşanıyor."},{"w":"fresh","tr":"taze","te":"Adjective","tt":"Sıfat","de":"Recently made, done, or picked","dt":"Yakın zamanda yapılmış, edilmiş veya toplanmış","e1":"I love the smell of fresh bread.","e1t":"Taze ekmek kokusunu severim.","e2":"This fish is not fresh.","e2t":"Bu balık taze değil."},{"w":"fridge","tr":"buzdolabı","te":"Noun","tt":"İsim","de":"A large container for keeping food cold","dt":"Yiyecekleri soğuk tutmak için büyük kap","e1":"Put the milk in the fridge.","e1t":"Sütü buzdolabına koy.","e2":"The fridge is empty.","e2t":"Buzdolabı boş."},{"w":"fridge / refrigerator","tr":"buzdolabı","te":"Noun","tt":"İsim","de":"A large cold box for keeping food","dt":"Yiyecek saklamak için büyük soğuk kutu","e1":"Put the milk in the fridge.","e1t":"Sütü buzdolabına koy.","e2":"The fridge is empty.","e2t":"Buzdolabı boş."},{"w":"friendly","tr":"arkadaş canlısı","te":"Adjective","tt":"Sıfat","de":"Kind and pleasant","dt":"Nazik ve hoş","e1":"The people here are very friendly.","e1t":"Buradaki insanlar çok arkadaş canlısı.","e2":"He has a friendly smile.","e2t":"Arkadaşça (sıcak) bir gülümsemesi var."},{"w":"friendship","tr":"arkadaşlık","te":"Noun","tt":"İsim","de":"A relationship between friends","dt":"Arkadaşlar arasındaki ilişki","e1":"Our friendship is very important to me.","e1t":"Arkadaşlığımız benim için çok önemli.","e2":"A true friendship lasts forever.","e2t":"Gerçek bir arkadaşlık sonsuza dek sürer."},{"w":"frighten","tr":"korkutmak","te":"Verb","tt":"Fiil","de":"To make someone afraid","dt":"Birini korkutmak","e1":"The loud noise frightened the baby.","e1t":"Yüksek ses bebeği korkuttu.","e2":"Don't frighten the cat!","e2t":"Kediyi korkutma!"},{"w":"frightened","tr":"korkmuş","te":"Adjective","tt":"Sıfat","de":"Feeling afraid","dt":"Korkmuş hissetme","e1":"She was frightened of the dark.","e1t":"Karanlıktan korkmuştu.","e2":"The frightened child started to cry.","e2t":"Korkmuş çocuk ağlamaya başladı."},{"w":"frightening","tr":"korkutucu","te":"Adjective","tt":"Sıfat","de":"Making you feel afraid","dt":"Sizi korkutan","e1":"It was a frightening experience.","e1t":"Korkutucu bir deneyimdi.","e2":"I don't like frightening movies.","e2t":"Korkutucu filmleri sevmem."},{"w":"frog","tr":"kurbağa","te":"Noun","tt":"İsim","de":"A small green animal that lives near water","dt":"Su kenarında yaşayan küçük yeşil hayvan","e1":"The frog jumped into the pond.","e1t":"Kurbağa gölete atladı.","e2":"Frogs eat insects.","e2t":"Kurbağalar böcek yer."},{"w":"front","tr":"ön","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The part that faces forward","dt":"Öne bakan kısım","e1":"Sign your name on the front of the form.","e1t":"İsminizi formun ön yüzüne imzalayın.","e2":"There is a garden in front of the house.","e2t":"Evin önünde bir bahçe var."},{"w":"frontier","tr":"sınır","te":"Noun","tt":"İsim","de":"The border between two countries","dt":"İki ülke arasındaki sınır","e1":"We crossed the frontier at midnight.","e1t":"Gece yarısı sınırı geçtik.","e2":"They are guarding the frontier.","e2t":"Sınırı koruyorlar."},{"w":"frost","tr":"don / kırağı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Thin white ice on surfaces when it is cold","dt":"Soğuk havada yüzeylerdeki ince beyaz buz","e1":"There was a heavy frost this morning.","e1t":"Bu sabah sert bir don (kırağı) vardı.","e2":"The windows were covered in frost.","e2t":"Camlar kırağı ile kaplıydı."},{"w":"frozen","tr":"donmuş","te":"Adjective","tt":"Sıfat","de":"Turned into ice or kept cold for preservation","dt":"Buz haline gelmiş veya korunma amaçlı soğuk tutulmuş","e1":"I bought some frozen vegetables.","e1t":"Biraz donmuş sebze aldım.","e2":"The lake is frozen.","e2t":"Göl donmuş."},{"w":"fry","tr":"kızartmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cook in hot oil","dt":"Sıcak yağda pişirmek","e1":"I'll fry some eggs for breakfast.","e1t":"Kahvaltı için biraz yumurta kızartacağım.","e2":"Do you want to fry the fish?","e2t":"Balığı kızartmak ister misin?"},{"w":"fuel","tr":"yakıt","te":"Noun/Verb","tt":"İsim/Fiil","de":"Substance burned for energy","dt":"Enerji için yakılan madde","e1":"This car uses a lot of fuel.","e1t":"Bu araba çok yakıt tüketiyor.","e2":"Wood is a traditional fuel.","e2t":"Odun geleneksel bir yakıttır."},{"w":"fulfill / fulfil","tr":"yerine getirmek / tamamlamak","te":"Verb","tt":"Fiil","de":"To do something promised or required","dt":"Vaat edilen veya gereken bir şeyi yapmak","e1":"He fulfilled his promise.","e1t":"Sözünü yerine getirdi.","e2":"I hope to fulfill my dreams.","e2t":"Hayallerimi gerçekleştirmeyi (tamamlamayı) umuyorum."},{"w":"full","tr":"dolu / tam","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Holding as much as possible","dt":"Mümkün olduğunca çok içeren","e1":"The glass is full of water.","e1t":"Bardak suyla dolu.","e2":"I am full, I can't eat anymore.","e2t":"Tokum (doluyum), daha fazla yiyemem."},{"w":"fully","tr":"tamamen","te":"Adverb","tt":"Zarf","de":"Completely","dt":"Bütünüyle","e1":"I fully understand the situation.","e1t":"Durumu tamamen anlıyorum.","e2":"The hotel is fully booked.","e2t":"Otel tamamen dolu (rezerveli)."},{"w":"fun","tr":"eğlence / eğlenceli","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Pleasure or enjoyment","dt":"Zevk veya keyif","e1":"We had a lot of fun at the party.","e1t":"Partide çok eğlendik.","e2":"Learning English is fun.","e2t":"İngilizce öğrenmek eğlencelidir."},{"w":"function","tr":"işlev","te":"Noun/Verb","tt":"İsim/Fiil","de":"The natural purpose of something","dt":"Bir şeyin doğal amacı","e1":"What is the function of this button?","e1t":"Bu butonun işlevi nedir?","e2":"The machine is not functioning correctly.","e2t":"Makine doğru çalışmıyor (işlev görmüyor)."},{"w":"fund","tr":"fon / sermaye / finanse etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money for a purpose","dt":"Bir amaç için ayrılan para","e1":"The government set up a disaster fund.","e1t":"Hükümet bir felaket fonu kurdu.","e2":"Who will fund the project?","e2t":"Projeyi kim finanse edecek?"},{"w":"fundamental","tr":"temel / esas","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Basic and important","dt":"Temel ve önemli","e1":"Freedom is a fundamental human right.","e1t":"Özgürlük temel bir insan hakkıdır.","e2":"We need to make fundamental changes.","e2t":"Temel değişiklikler yapmamız gerekiyor."},{"w":"fundamentally","tr":"esasen / temelden","te":"Adverb","tt":"Zarf","de":"In a basic or essential way","dt":"Temel veya esaslı bir yolla","e1":"The two systems are fundamentally different.","e1t":"İki sistem temelden farklıdır.","e2":"He is fundamentally a good person.","e2t":"O esasen iyi bir insandır."},{"w":"funeral","tr":"cenaze","te":"Noun","tt":"İsim","de":"A ceremony for a dead person","dt":"Ölü biri için yapılan tören","e1":"Many people attended the funeral.","e1t":"Cenazeye birçok kişi katıldı.","e2":"The funeral was held on Wednesday.","e2t":"Cenaze Çarşamba günü yapıldı."},{"w":"funny","tr":"komik / tuhaf","te":"Adjective","tt":"Sıfat","de":"Making you laugh or strange","dt":"Sizi güldüren veya garip","e1":"He told a funny joke.","e1t":"Komik bir şaka yaptı.","e2":"I have a funny feeling about this.","e2t":"Bununla ilgili tuhaf bir hissim var."},{"w":"fur","tr":"kürk / tüy","te":"Noun","tt":"İsim","de":"The thick hair that covers animals","dt":"Hayvanları örten kalın tüyler","e1":"The cat has soft white fur.","e1t":"Kedinin yumuşak beyaz kürkü var.","e2":"I don't wear real fur.","e2t":"Gerçek kürk giymem."},{"w":"furious","tr":"çok öfkeli","te":"Adjective","tt":"Sıfat","de":"Extremely angry","dt":"Son derece kızgın","e1":"He was furious with me for being late.","e1t":"Geç kaldığım için bana çok öfkeliydi.","e2":"She gave him a furious look.","e2t":"Ona öfkeli bir bakış attı."},{"w":"furniture","tr":"mobilya","te":"Noun","tt":"İsim","de":"Large objects such as tables and chairs","dt":"Masa ve sandalye gibi büyük nesneler","e1":"We need to buy new furniture for the living room.","e1t":"Oturma odası için yeni mobilya almamız gerekiyor.","e2":"This furniture is very old.","e2t":"Bu mobilya çok eski."},{"w":"further","tr":"daha fazla","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Comparative of far; more or additional","dt":"Far'ın karşılaştırmalı hali; daha çok veya ek","e1":"Do you have any further questions?","e1t":"Başka (daha fazla) sorunuz var mı?","e2":"The station is further than I thought.","e2t":"İstasyon düşündüğümden daha uzakta."},{"w":"furthermore","tr":"dahası / ayrıca","te":"Adverb","tt":"Zarf","de":"In addition to what has been said","dt":"Söylenenlere ek olarak","e1":"Furthermore, the price is too high.","e1t":"Dahası, fiyat çok yüksek.","e2":"He is clever; furthermore, he is hardworking.","e2t":"Zekidir; ayrıca çalışkandır."},{"w":"future","tr":"gelecek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The time that will come after now","dt":"Şimdiden sonra gelecek olan zaman","e1":"What are your plans for the future?","e1t":"Gelecek için planların ne?","e2":"We need to think about the future.","e2t":"Geleceği düşünmemiz gerekiyor."},{"w":"gain","tr":"kazanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get something useful or an increase","dt":"Yararlı bir şey elde etmek veya artış","e1":"You will gain experience in this job.","e1t":"Bu işte deneyim kazanacaksın.","e2":"What do you hope to gain?","e2t":"Ne kazanmayı umuyorsun?"},{"w":"gallery","tr":"galeri","te":"Noun","tt":"İsim","de":"A room or building for showing art","dt":"Sanat göstermek için oda veya bina","e1":"Let's visit the art gallery.","e1t":"Hadi sanat galerisini ziyaret edelim.","e2":"The gallery has a beautiful collection.","e2t":"Galerinin güzel bir koleksiyonu var."},{"w":"gap","tr":"boşluk / fark","te":"Noun","tt":"İsim","de":"An empty space or a big difference","dt":"Boş bir alan veya büyük bir fark","e1":"There is a gap in the fence.","e1t":"Çit içinde bir boşluk var.","e2":"The gap between the rich and the poor is growing.","e2t":"Zengin ve fakir arasındaki fark (uçurum) büyüyor."},{"w":"garage","tr":"garaj / tamirhane","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place to keep or repair cars","dt":"Arabaları saklamak veya tamir etmek için yer","e1":"Park the car in the garage.","e1t":"Arabayı garaja park et.","e2":"My car is at the garage for repairs.","e2t":"Arabam tamir için tamirhanede."},{"w":"garbage","tr":"çöp","te":"Noun","tt":"İsim","de":"Waste material or rubbish","dt":"Atık malzeme veya çöp","e1":"Take out the garbage, please.","e1t":"Lütfen çöpü dışarı çıkar.","e2":"Don't throw garbage on the street.","e2t":"Sokağa çöp atma."},{"w":"garlic","tr":"sarımsak","te":"Noun","tt":"İsim","de":"A plant with a strong taste used in cooking","dt":"Yemekte kullanılan güçlü tadı olan bitki","e1":"Add two cloves of garlic.","e1t":"İki diş sarımsak ekle.","e2":"I don't like the smell of garlic.","e2t":"Sarımsak kokusunu sevmem."},{"w":"gas","tr":"gaz","te":"Noun","tt":"İsim","de":"A substance like air or fuel for heating","dt":"Hava gibi bir madde veya ısınma için yakıt","e1":"We cook with gas.","e1t":"Gazla yemek pişiriyoruz.","e2":"Is there a gas station near here?","e2t":"Buralarda yakınlarda bir benzin istasyonu (gaz istasyonu) var mı?"},{"w":"gate","tr":"kapı / geçit","te":"Noun","tt":"İsim","de":"A door in a fence or at an airport","dt":"Çit üzerindeki kapı veya havaalanındaki biniş kapısı","e1":"Please close the garden gate.","e1t":"Lütfen bahçe kapısını kapat.","e2":"Your flight is at gate 15.","e2t":"Uçuşunuz 15 numaralı kapıda."},{"w":"gather","tr":"toplamak / toplanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come together or collect things","dt":"Bir araya gelmek veya eşyaları toplamak","e1":"A crowd gathered in the square.","e1t":"Meydanda bir kalabalık toplandı.","e2":"Gather your things, we're leaving.","e2t":"Eşyalarını topla, gidiyoruz."},{"w":"gathering","tr":"toplantı / buluşma","te":"Noun","tt":"İsim","de":"A meeting of a group of people","dt":"Bir grup insanın toplantısı","e1":"We had a small family gathering.","e1t":"Küçük bir aile buluşması yaptık.","e2":"It was a social gathering.","e2t":"Sosyal bir toplantıydı."},{"w":"gear","tr":"dişli / vites / ekipman","te":"Noun/Verb","tt":"İsim/Fiil","de":"A part of a machine or equipment","dt":"Makine parçası veya ekipman","e1":"Change the gear, please.","e1t":"Lütfen vitesi değiştir.","e2":"He bought new diving gear.","e2t":"Yeni dalış ekipmanı satın aldı."},{"w":"general","tr":"genel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Affecting most people or not specific","dt":"Çoğu kişiyi etkileyen veya spesifik olmayan","e1":"This is a general rule.","e1t":"Bu genel bir kuraldır.","e2":"Tell me the general idea.","e2t":"Bana genel fikri söyle."},{"w":"generally","tr":"genellikle","te":"Adverb","tt":"Zarf","de":"Usually or in most cases","dt":"Genellikle veya çoğu durumda","e1":"I generally wake up at 7 AM.","e1t":"Genellikle sabah 7'de uyanırım.","e2":"It is generally believed that...","e2t":"Genellikle ... inanılır."},{"w":"generate","tr":"üretmek / oluşturmak","te":"Verb","tt":"Fiil","de":"To produce or create something","dt":"Bir şey üretmek veya oluşturmak","e1":"Wind turbines generate electricity.","e1t":"Rüzgar türbinleri elektrik üretir.","e2":"We need to generate new ideas.","e2t":"Yeni fikirler üretmeliyiz."},{"w":"generation","tr":"nesil","te":"Noun","tt":"İsim","de":"All the people born around the same time","dt":"Yaklaşık aynı zamanda doğan tüm insanlar","e1":"The younger generation loves technology.","e1t":"Genç nesil teknolojiyi seviyor.","e2":"We have three generations in one house.","e2t":"Bir evde üç nesiliz."},{"w":"generous","tr":"cömert","te":"Adjective","tt":"Sıfat","de":"Giving more than is expected","dt":"Beklenenden fazlasını veren","e1":"Thank you for your generous gift.","e1t":"Cömert hediyeniz için teşekkürler.","e2":"He is a very generous man.","e2t":"O çok cömert bir adamdır."},{"w":"gentle","tr":"nazik","te":"Adjective","tt":"Sıfat","de":"Calm, kind, or soft","dt":"Sakin, nazik veya yumuşak","e1":"He is a very gentle person.","e1t":"O çok nazik (centilmen) bir insandır.","e2":"Be gentle with the baby.","e2t":"Bebeğe karşı nazik ol."},{"w":"gentleman","tr":"beyefendi","te":"Noun","tt":"İsim","de":"A polite or well","dt":"behaved man","e1":"Nazik veya terbiyeli adam","e1t":"He is a true gentleman.","e2":"O gerçek bir beyefendidir.","e2t":"Ladies and gentlemen, welcome!"},{"w":"gently","tr":"nazikçe / yavaşça","te":"Adverb","tt":"Zarf","de":"In a gentle way","dt":"Nazik bir yolla","e1":"He closed the door gently.","e1t":"Kapıyı nazikçe kapattı.","e2":"Handle the glass gently.","e2t":"Camı yavaşça (dikkatle) taşıyın."},{"w":"geography","tr":"coğrafya","te":"Noun","tt":"İsim","de":"The study of the earth's physical features","dt":"Dünyanın fiziksel özelliklerinin incelenmesi","e1":"I like learning about world geography.","e1t":"Dünya coğrafyası hakkında bilgi edinmeyi severim.","e2":"Geography was my favorite subject.","e2t":"Coğrafya en sevdiğim dersti."},{"w":"gesture","tr":"jest","te":"Noun/Verb","tt":"İsim/Fiil","de":"A movement of the hands or face to express something","dt":"Bir şeyi ifade etmek için el veya yüz hareketleri","e1":"He made a gesture of greeting.","e1t":"Bir selamlama jesti yaptı.","e2":"It was a very kind gesture.","e2t":"Çok nazikçe bir hareketti (jestti)."},{"w":"get","tr":"almak / ulaşmak / olmak","te":"Verb","tt":"Fiil","de":"To receive, obtain, or reach","dt":"Almak, elde etmek veya ulaşmak","e1":"Did you get my email?","e1t":"E","e2":"postamı aldın mı?","e2t":"I am getting tired."},{"w":"ghost","tr":"hayalet","te":"Noun","tt":"İsim","de":"The spirit of a dead person","dt":"Ölü bir kişinin ruhu","e1":"Do you believe in ghosts?","e1t":"Hayaletlere inanır mısın?","e2":"The old house is said to be haunted by a ghost.","e2t":"Eski evin bir hayalet tarafından mesken tutulduğu söylenir."},{"w":"giant","tr":"dev","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Extremely large","dt":"Son derece büyük","e1":"The project was a giant success.","e1t":"Proje devasa bir başarıydı.","e2":"He is a giant in the industry.","e2t":"O endüstride bir devdir."},{"w":"giraffe","tr":"zürafa","te":"Noun","tt":"İsim","de":"A tall animal with a very long neck","dt":"Çok uzun boyunlu, yüksek hayvan","e1":"The giraffe eats leaves.","e1t":"Zürafa yaprak yer.","e2":"A tall giraffe.","e2t":"Uzun bir zürafa."},{"w":"girlfriend","tr":"kız arkadaş","te":"Noun","tt":"İsim","de":"A female friend in a romantic relationship","dt":"Romantik bir ilişkideki kadın arkadaş","e1":"He is going to dinner with his girlfriend.","e1t":"Kız arkadaşıyla yemeğe gidiyor.","e2":"Is she your girlfriend?","e2t":"O senin kız arkadaşın mı?"},{"w":"glad","tr":"memnun / mutlu","te":"Adjective","tt":"Sıfat","de":"Happy or pleased","dt":"Mutlu veya memnun","e1":"I'm so glad to see you!","e1t":"Seni gördüğüme çok memnun oldum!","e2":"He was glad that the meeting was over.","e2t":"Toplantı bittiği için mutluydu."},{"w":"glass","tr":"cam / bardak","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard transparent material or a container","dt":"Sert şeffaf madde veya kap","e1":"Be careful, the glass is broken.","e1t":"Dikkat et, cam kırık.","e2":"I’d like a glass of water, please.","e2t":"Bir bardak su rica ediyorum lütfen."},{"w":"glasses","tr":"gözlük","te":"Noun","tt":"İsim","de":"A pair of lenses used to see better","dt":"Daha iyi görmek için kullanılan mercek çifti","e1":"I need new reading glasses.","e1t":"Yeni okuma gözlüğüne ihtiyacım var.","e2":"Where are my glasses?","e2t":"Gözlüğüm nerede?"},{"w":"global","tr":"küresel","te":"Adjective","tt":"Sıfat","de":"Relating to the whole world","dt":"Tüm dünya ile ilgili olan","e1":"Global warming is a serious problem.","e1t":"Küresel ısınma ciddi bir sorundur.","e2":"We live in a global economy.","e2t":"Küresel bir ekonomide yaşıyoruz."},{"w":"globe","tr":"küre / dünya","te":"Noun/Verb","tt":"İsim/Fiil","de":"A round model of the Earth or the world","dt":"Dünyanın yuvarlak modeli veya dünya","e1":"He looked for Turkey on the globe.","e1t":"Küre üzerinde Türkiye'yi aradı.","e2":"Travelers from all over the globe.","e2t":"Dünyanın her yerinden gezginler."},{"w":"glory","tr":"görkem / zafer","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great fame or honor","dt":"Büyük şöhret veya onur","e1":"He returned home in glory.","e1t":"Eve zaferle (görkemle) döndü.","e2":"They fought for the glory of their country.","e2t":"Ülkelerinin görkemi için savaştılar."},{"w":"glove","tr":"eldiven","te":"Noun","tt":"İsim","de":"A covering for the hand with separate parts for fingers","dt":"Parmaklar için ayrı kısımları olan el örtüsü","e1":"Wear your gloves, it's freezing!","e1t":"Eldivenlerini giy, hava buz gibi!","e2":"I lost my left glove.","e2t":"Sol eldivenimi kaybettim."},{"w":"glue","tr":"yapıştırıcı / yapıştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance used to join things together","dt":"Şeyleri birleştirmek için kullanılan madde","e1":"I need some glue to fix this.","e1t":"Bunu tamir etmek için biraz yapıştırıcıya ihtiyacım var.","e2":"He glued the pieces back together.","e2t":"Parçaları tekrar birbirine yapıştırdı."},{"w":"goal","tr":"hedef","te":"Noun","tt":"İsim","de":"Something you want to achieve or a point in sports","dt":"Başarmak istediğiniz bir şey veya sporda sayı/gol","e1":"My goal is to speak English fluently.","e1t":"Hedefim akıcı İngilizce konuşmak.","e2":"He scored a goal in the match.","e2t":"Maçta bir gol attı."},{"w":"goat","tr":"keçi","te":"Noun","tt":"İsim","de":"A farm animal with horns and a beard","dt":"Boynuzlu ve sakallı çiftlik hayvanı","e1":"The goat is grazing on the hill.","e1t":"Keçi tepede otluyor.","e2":"Goat cheese is very delicious.","e2t":"Keçi peyniri çok lezzetlidir."},{"w":"god","tr":"tanrı","te":"Noun","tt":"İsim","de":"A being worshipped as the creator","dt":"Yaratıcı olarak tapılan varlık","e1":"Do you believe in God?","e1t":"Tanrı'ya inanıyor musun?","e2":"Oh my God!","e2t":"Aman Tanrım!"},{"w":"gold","tr":"altın","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A yellow precious metal","dt":"Sarı değerli metal","e1":"This ring is made of gold.","e1t":"Bu yüzük altından yapılmış.","e2":"He won a gold medal.","e2t":"Altın madalya kazandı."},{"w":"golden","tr":"altın gibi / çok değerli","te":"Adjective","tt":"Sıfat","de":"Made of gold or very successful/special","dt":"Altından yapılmış veya çok başarılı/özel","e1":"This is a golden opportunity.","e1t":"Bu altın (eşsiz) bir fırsattır.","e2":"He has golden hair.","e2t":"Altın rengi (sapsarı) saçları var."},{"w":"golf","tr":"golf","te":"Noun/Verb","tt":"İsim/Fiil","de":"A game played with a club and a small ball","dt":"Sopa ve küçük bir topla oynanan oyun","e1":"He likes playing golf on weekends.","e1t":"Hafta sonları golf oynamayı sever.","e2":"There is a big golf course near the hotel.","e2t":"Otelin yakınında büyük bir golf sahası var."},{"w":"good","tr":"looking","te":"iyi görünen","tt":"Adjective","de":"Sıfat","dt":"Physically attractive","e1":"Fiziksel olarak çekici","e1t":"He is a very good","e2":"looking man.","e2t":"O çok yakışıklı (iyi görünen) bir adamdır."},{"w":"goods","tr":"mallar / eşyalar","te":"Noun","tt":"İsim","de":"Things that are produced to be sold","dt":"Satılmak için üretilen şeyler","e1":"The shop sells leather goods.","e1t":"Dükkan deri eşyalar (mallar) satıyor.","e2":"Electrical goods are expensive.","e2t":"Elektrikli mallar pahalıdır."},{"w":"govern","tr":"yönetmek","te":"Verb","tt":"Fiil","de":"To control or direct a country/org","dt":"Bir ülkeyi veya organizasyonu yönetmek","e1":"They govern the country well.","e1t":"Ülkeyi iyi yönetiyorlar.","e2":"The rules govern how the game is played.","e2t":"Kurallar oyunun nasıl oynanacağını yönetir (belirler)."},{"w":"government","tr":"hükümet","te":"Noun","tt":"İsim","de":"The group of people who rule a country","dt":"Bir ülkeyi yöneten insanlar grubu","e1":"The government is planning new taxes.","e1t":"Hükümet yeni vergiler planlıyor.","e2":"He works for the local government.","e2t":"Yerel hükümet için çalışıyor."},{"w":"governor","tr":"vali / yönetici","te":"Noun","tt":"İsim","de":"A person who governs a province or state","dt":"Bir ili veya eyaleti yöneten kişi","e1":"The governor of Istanbul visited the school.","e1t":"İstanbul valisi okulu ziyaret etti.","e2":"He was elected as the new governor.","e2t":"Yeni vali olarak seçildi."},{"w":"grab","tr":"kapmak / tutmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take something suddenly and roughly","dt":"Bir şeyi aniden ve sertçe almak","e1":"Grab your coat, we're late!","e1t":"Montunu kap, geç kaldık!","e2":"He grabbed my arm.","e2t":"Kolumu tuttu (kaptı)."},{"w":"grace","tr":"zarafet / lütuf","te":"Noun/Verb","tt":"İsim/Fiil","de":"Smoothness of movement or politeness","dt":"Hareket pürüzsüzlüğü veya nezaket","e1":"She moves with great grace.","e1t":"Büyük bir zarafetle hareket ediyor.","e2":"By the grace of God.","e2t":"Allah'ın lütfuyla."},{"w":"grade","tr":"sınıf / not / derece","te":"Noun/Verb","tt":"İsim/Fiil","de":"A level of quality or a mark in school","dt":"Kalite seviyesi veya okuldaki not","e1":"He got a good grade in the exam.","e1t":"Sınavdan iyi bir not aldı.","e2":"I am in the tenth grade.","e2t":"Onuncu sınıftayım."},{"w":"gradual","tr":"kademeli / yavaş yavaş","te":"Adjective","tt":"Sıfat","de":"Happening slowly over a period of time","dt":"Zaman içinde yavaşça gerçekleşen","e1":"There was a gradual change in the climate.","e1t":"İklimde kademeli bir değişiklik vardı.","e2":"He showed a gradual improvement.","e2t":"Kademeli bir iyileşme gösterdi."},{"w":"gradually","tr":"yavaş yavaş / kademeli olarak","te":"Adverb","tt":"Zarf","de":"Slowly and by degrees","dt":"Yavaşça ve derece derece","e1":"His English is gradually improving.","e1t":"İngilizcesi yavaş yavaş gelişiyor.","e2":"The weather is gradually getting warmer.","e2t":"Hava yavaş yavaş ısınıyor."},{"w":"graduate","tr":"mezun olmak / mezun","te":"Verb/Noun","tt":"Fiil/İsim","de":"To complete school or university","dt":"Okulu veya üniversiteyi bitirmek","e1":"He graduated from university last year.","e1t":"Geçen yıl üniversiteden mezun oldu.","e2":"She is a Harvard graduate.","e2t":"O bir Harvard mezunudur."},{"w":"graduation","tr":"mezuniyet","te":"Noun","tt":"İsim","de":"The ceremony of completing a course","dt":"Bir kursu tamamlama töreni","e1":"The graduation ceremony was beautiful.","e1t":"Mezuniyet töreni güzeldi.","e2":"I missed my brother's graduation.","e2t":"Erkek kardeşimin mezuniyetini kaçırdım."},{"w":"grain","tr":"tahıl / tanecik","te":"Noun","tt":"İsim","de":"A small hard seed or a tiny piece","dt":"Küçük sert tohum veya minik parça","e1":"Wheat is a type of grain.","e1t":"Buğday bir tahıl türüdür.","e2":"There was a grain of sand in my eye.","e2t":"Gözümde bir kum tanesi vardı."},{"w":"grammar","tr":"gramer","te":"Noun","tt":"İsim","de":"The rules about how words are used in a language","dt":"Bir dilde kelimelerin nasıl kullanılacağına dair kurallar","e1":"English grammar is not very difficult.","e1t":"İngilizce grameri çok zor değil.","e2":"You should study your grammar.","e2t":"Gramerine çalışmalısın."},{"w":"grand","tr":"büyük / görkemli","te":"Adjective","tt":"Sıfat","de":"Very large and impressive","dt":"Çok büyük ve etkileyici","e1":"The hotel has a grand entrance.","e1t":"Otelin görkemli bir girişi var.","e2":"It was a grand wedding.","e2t":"Görkemli bir düğündü."},{"w":"grandchild","tr":"torun","te":"Noun","tt":"İsim","de":"The child of one's son or daughter","dt":"Birinin oğlunun veya kızının çocuğu","e1":"They have five grandchildren.","e1t":"Beş torunları var.","e2":"He is visiting his grandchild.","e2t":"Torununu ziyaret ediyor."},{"w":"granddaughter","tr":"kız torun","te":"Noun","tt":"İsim","de":"A female grandchild","dt":"Kadın torun","e1":"My granddaughter is starting school.","e1t":"Kız torunum okula başlıyor.","e2":"She is the granddaughter of a famous artist.","e2t":"Ünlü bir sanatçının kız torunudur."},{"w":"grandfather","tr":"büyükbaba / dede","te":"Noun","tt":"İsim","de":"The father of one's father or mother","dt":"Birinin babasının veya annesinin babası","e1":"My grandfather is 80 years old.","e1t":"Büyükbabam 80 yaşında.","e2":"He loves his grandfather very much.","e2t":"Dedesi çok seviyor."},{"w":"grandmother","tr":"büyükanne / nene","te":"Noun","tt":"İsim","de":"The mother of one's father or mother","dt":"Birinin babasının veya annesinin annesi","e1":"My grandmother makes delicious cookies.","e1t":"Büyükannem lezzetli kurabiyeler yapar.","e2":"Her grandmother lives in a village.","e2t":"Büyükannesi bir köyde yaşıyor."},{"w":"grandparent","tr":"büyükanne/büyükbaba","te":"Noun","tt":"İsim","de":"The parents of your father or mother","dt":"Annenizin veya babanızın ebeveynleri","e1":"I visit my grandparents every summer.","e1t":"Her yaz büyükanne ve büyükbabamı ziyaret ederim.","e2":"My grandparents are very old.","e2t":"Büyükanne ve büyükbabam çok yaşlılar."},{"w":"grandson","tr":"erkek torun","te":"Noun","tt":"İsim","de":"A male grandchild","dt":"Erkek torun","e1":"He is my oldest grandson.","e1t":"O benim en büyük erkek torunum.","e2":"The grandson looks like his grandfather.","e2t":"Erkek torun dedesine benziyor."},{"w":"grant","tr":"hibe / bağış / vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money or to allow something","dt":"Bir miktar para veya bir şeye izin vermek","e1":"The university gave him a research grant.","e1t":"Üniversite ona bir araştırma hibesi verdi.","e2":"They granted him permission to stay.","e2t":"Ona kalma izni verdiler (bahşettiler)."},{"w":"graph","tr":"grafik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A drawing showing the relationship between numbers","dt":"Sayılar arasındaki ilişkiyi gösteren çizim","e1":"Look at the graph on the screen.","e1t":"Ekrandaki grafiğe bak.","e2":"The graph shows a rise in sales.","e2t":"Grafik satışlarda bir artış gösteriyor."},{"w":"graphics","tr":"grafikler (görsel)","te":"Noun","tt":"İsim","de":"Images and designs used in books/computers","dt":"Kitaplarda/bilgisayarlarda kullanılan görüntüler ve tasarımlar","e1":"The graphics in this video game are amazing.","e1t":"Bu video oyunundaki grafikler harika.","e2":"He works in computer graphics.","e2t":"Bilgisayar grafikleri alanında çalışıyor."},{"w":"grasp","tr":"kavramak / anlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hold firmly or to understand","dt":"Sıkıca tutmak veya anlamak","e1":"He grasped my hand.","e1t":"Elim sıkıca kavradı.","e2":"I can't grasp the meaning of this sentence.","e2t":"Bu cümlenin anlamını kavrayamıyorum (anlayamıyorum)."},{"w":"grass","tr":"çim / ot","te":"Noun/Verb","tt":"İsim/Fiil","de":"A common green plant that covers the ground","dt":"Yeri kaplayan yaygın yeşil bitki","e1":"Don't walk on the grass.","e1t":"Çimlerin üzerinde yürümeyin.","e2":"The grass is very green after the rain.","e2t":"Yağmurdan sonra çimler çok yeşil."},{"w":"grateful","tr":"minnettar","te":"Adjective","tt":"Sıfat","de":"Feeling or showing thanks","dt":"Teşekkür hissetme veya gösterme","e1":"I am grateful for your help.","e1t":"Yardımın için minnettarım.","e2":"She was grateful to be alive.","e2t":"Hayatta olduğu için minnettardı."},{"w":"gravity","tr":"yerçekimi / ciddiyet","te":"Noun","tt":"İsim","de":"The force that pulls objects toward the earth","dt":"Nesneleri dünyaya çeken kuvvet","e1":"Gravity keeps us on the ground.","e1t":"Yerçekimi bizi yerde tutar.","e2":"I don't think you understand the gravity of the situation.","e2t":"Durumun ciddiyetini anladığınızı sanmıyorum."},{"w":"gray / grey","tr":"gri","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The color between black and white","dt":"Siyah ve beyaz arasındaki renk","e1":"The sky is gray today.","e1t":"Bugün gökyüzü gri.","e2":"He has gray hair.","e2t":"Gri (kır) saçları var."},{"w":"great","tr":"harika / büyük","te":"Adjective","tt":"Sıfat","de":"Very good or large in size/amount","dt":"Çok iyi veya boyut/miktar olarak büyük","e1":"That’s a great idea!","e1t":"Bu harika bir fikir!","e2":"He was a great leader.","e2t":"O büyük bir liderdi."},{"w":"greatly","tr":"büyük ölçüde","te":"Adverb","tt":"Zarf","de":"Very much","dt":"Çok fazla","e1":"Your help is greatly appreciated.","e1t":"Yardımın büyük ölçüde takdir ediliyor.","e2":"The situation has changed greatly.","e2t":"Durum büyük ölçüde değişti."},{"w":"greed","tr":"açgözlülük","te":"Noun","tt":"İsim","de":"A strong desire for more money, food, etc.","dt":"Daha fazla para, yemek vb. için duyulan güçlü arzu","e1":"His greed led to his downfall.","e1t":"Onun açgözlülüğü çöküşüne neden oldu.","e2":"Greed can ruin lives.","e2t":"Açgözlülük hayatları mahvedebilir."},{"w":"greedy","tr":"açgözlü","te":"Adjective","tt":"Sıfat","de":"Wanting more than you need","dt":"İhtiyacından fazlasını isteme","e1":"Don't be greedy, share your toys.","e1t":"Açgözlü olma, oyuncaklarını paylaş.","e2":"He is greedy for power.","e2t":"Güce karşı açgözlüdür."},{"w":"greet","tr":"selamlamak","te":"Verb","tt":"Fiil","de":"To say hello to someone","dt":"Birine merhaba demek","e1":"He greeted me with a smile.","e1t":"Beni bir gülümsemeyle selamladı.","e2":"The host greeted the guests at the door.","e2t":"Ev sahibi misafirleri kapıda karşıladı (selamladı)."},{"w":"greeting","tr":"selamlama","te":"Noun","tt":"İsim","de":"Something you say or do when you meet someone","dt":"Biriyle tanıştığınızda söylediğiniz veya yaptığınız şey","e1":"\"Hello\" is a common greeting.","e1t":"\"Merhaba\" yaygın bir selamlamadır.","e2":"Send them my greetings.","e2t":"Onlara selamlarımı ilet."},{"w":"grid","tr":"ızgara / şebeke","te":"Noun","tt":"İsim","de":"A pattern of straight lines that cross each other","dt":"Birbirini kesen düz çizgiler deseni","e1":"The city streets are laid out in a grid.","e1t":"Şehir sokakları bir ızgara (kareli sistem) şeklinde düzenlenmiştir.","e2":"The national power grid.","e2t":"Ulusal elektrik şebekesi."},{"w":"grief","tr":"keder / derin üzüntü","te":"Noun","tt":"İsim","de":"Very great sadness, especially at someone's death","dt":"Özellikle birinin ölümü üzerine duyulan büyük üzüntü","e1":"She was overcome with grief.","e1t":"Kederden perişan oldu.","e2":"Time heals grief.","e2t":"Zaman kederi iyileştirir."},{"w":"grill","tr":"ızgara / ızgara yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A metal frame for cooking food over a fire","dt":"Ateş üzerinde yemek pişirmek için metal çerçeve","e1":"Put the chicken on the grill.","e1t":"Tavuğu ızgaraya koy.","e2":"I like grilled vegetables.","e2t":"Izgara sebzeleri severim."},{"w":"grin","tr":"sırıtmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To smile widely","dt":"Genişçe gülümsemek","e1":"He grinned at me.","e1t":"Bana sırıttı.","e2":"She had a big grin on her face.","e2t":"Yüzünde kocaman bir sırıtış vardı."},{"w":"grind","tr":"öğütmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To crush something into powder","dt":"Bir şeyi ezerek toz haline getirmek","e1":"I need to grind some coffee beans.","e1t":"Biraz kahve çekirdeği öğütmem gerekiyor.","e2":"The mill grinds wheat into flour.","e2t":"Değirmen buğdayı öğüterek un haline getirir."},{"w":"grip","tr":"sıkıca tutmak / kavrama","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hold something tightly","dt":"Bir şeyi sıkıca tutmak","e1":"Grip the handle firmly.","e1t":"Kolu sıkıca kavra.","e2":"I lost my grip and fell.","e2t":"Tutuşumu (kavramamı) kaybettim ve düştüm."},{"w":"grocery","tr":"market alışverişi","te":"Noun","tt":"İsim","de":"Food and other goods sold by a grocer","dt":"Bakkal/market tarafından satılan yiyecek ve mallar","e1":"I need to do some grocery shopping.","e1t":"Biraz market alışverişi yapmam gerekiyor.","e2":"Where is the nearest grocery store?","e2t":"En yakın bakkal/market nerede?"},{"w":"gross","tr":"brüt / iğrenç","te":"Adjective/Noun/Verb","tt":"Total amount before tax or disgusting","de":"Vergiden önceki toplam miktar veya iğrenç","dt":"What is your gross income?","e1":"Brüt geliriniz nedir?","e1t":"That’s gross!","e2":"Bu iğrenç!","e2t":""},{"w":"ground","tr":"zemin","te":"Noun","tt":"İsim","de":"The surface of the earth","dt":"Yeryüzünün yüzeyi","e1":"Don't sit on the cold ground.","e1t":"Soğuk zemine oturma.","e2":"The ground was covered with snow.","e2t":"Yer karla kaplıydı."},{"w":"group","tr":"grup","te":"Noun","tt":"İsim","de":"A number of people or things together","dt":"Bir arada bulunan bir dizi insan veya şey","e1":"We work in small groups.","e1t":"Küçük gruplar halinde çalışıyoruz.","e2":"A group of students is waiting outside.","e2t":"Bir grup öğrenci dışarıda bekliyor."},{"w":"grow","tr":"büyümek","te":"Verb","tt":"Fiil","de":"To increase in size or develop","dt":"Boyut olarak artmak veya gelişmek","e1":"Children grow very fast.","e1t":"Çocuklar çok hızlı büyür.","e2":"He wants to grow his business.","e2t":"İşini büyütmek istiyor."},{"w":"growth","tr":"büyüme","te":"Noun","tt":"İsim","de":"The process of developing or increasing","dt":"Gelişme veya artma süreci","e1":"The company saw a rapid growth last year.","e1t":"Şirket geçen yıl hızlı bir büyüme gördü.","e2":"Economic growth is important.","e2t":"Ekonomik büyüme önemlidir."},{"w":"guarantee","tr":"garanti / garanti etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A promise that something will happen/work","dt":"Bir şeyin olacağına/çalışacağına dair söz","e1":"The phone comes with a one","e1t":"year guarantee.","e2":"Telefon bir yıllık garanti ile geliyor.","e2t":"I guarantee that you will like it."},{"w":"guard","tr":"koruma / korumak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who protects or to protect","dt":"Koruyan kişi veya korumak","e1":"There is a security guard at the door.","e1t":"Kapıda bir güvenlik görevlisi (koruma) var.","e2":"The dog is guarding the house.","e2t":"Köpek evi koruyor."},{"w":"guerrilla","tr":"gerilla","te":"Noun","tt":"İsim","de":"A member of an unofficial military group","dt":"Resmi olmayan askeri grubun üyesi","e1":"He joined the guerrilla forces.","e1t":"Gerilla kuvvetlerine katıldı.","e2":"Guerrilla warfare is difficult.","e2t":"Gerilla savaşı zordur."},{"w":"guess","tr":"tahmin etmek / tahmin","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give an answer without being sure","dt":"Emin olmadan cevap vermek","e1":"Can you guess my age?","e1t":"Yaşımı tahmin edebilir misin?","e2":"My guess was correct.","e2t":"Tahminim doğruydu."},{"w":"guest","tr":"misafir","te":"Noun","tt":"İsim","de":"A person who is invited to stay or eat","dt":"Kalmaya veya yemek yemeye davet edilen kişi","e1":"We have guests for dinner tonight.","e1t":"Bu akşam akşam yemeği için misafirlerimiz var.","e2":"How many guests are at the wedding?","e2t":"Düğünde kaç misafir var?"},{"w":"guide","tr":"rehber","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who shows the way to others","dt":"Başkalarına yolu gösteren kişi","e1":"The tour guide was very helpful.","e1t":"Tur rehberi çok yardımcıydı.","e2":"He guided us through the forest.","e2t":"Ormanda bize rehberlik etti."},{"w":"guideline","tr":"kılavuz / prensip","te":"Noun","tt":"İsim","de":"Information on how something should be done","dt":"Bir şeyin nasıl yapılması gerektiğine dair bilgi","e1":"Follow the safety guidelines.","e1t":"Güvenlik kılavuzlarına (prensiplerine) uyun.","e2":"The government issued new guidelines.","e2t":"Hükümet yeni yönergeler/kılavuzlar yayınladı."},{"w":"guilt","tr":"suçluluk","te":"Noun","tt":"İsim","de":"A feeling of having done something wrong","dt":"Yanlış bir şey yapmış olma hissi","e1":"He felt a sense of guilt.","e1t":"Bir suçluluk duygusu hissetti.","e2":"The jury decided on his guilt.","e2t":"Jüri onun suçluluğuna karar verdi."},{"w":"guilty","tr":"suçlu","te":"Adjective","tt":"Sıfat","de":"Responsible for a crime or feeling guilt","dt":"Bir suçtan sorumlu veya suçluluk duyan","e1":"The judge found him guilty.","e1t":"Yargıç onu suçlu buldu.","e2":"I feel guilty about eating the whole cake.","e2t":"Kekin tamamını yediğim için suçlu hissediyorum."},{"w":"guitar","tr":"gitar","te":"Noun","tt":"İsim","de":"A musical instrument with strings","dt":"Telli bir müzik aleti","e1":"He plays the guitar very well.","e1t":"Çok iyi gitar çalıyor.","e2":"I want to learn how to play the guitar.","e2t":"Gitar çalmayı öğrenmek istiyorum."},{"w":"guitarist","tr":"gitarist","te":"Noun","tt":"İsim","de":"A person who plays the guitar","dt":"Gitar çalan kişi","e1":"He is a famous rock guitarist.","e1t":"O ünlü bir rock gitaristidir.","e2":"I want to be a professional guitarist.","e2t":"Profesyonel bir gitarist olmak istiyorum."},{"w":"gulf","tr":"körfez","te":"Noun","tt":"İsim","de":"A large area of sea partly surrounded by land","dt":"Kısmen kara ile çevrili geniş deniz alanı","e1":"The Persian Gulf is rich in oil.","e1t":"Basra Körfezi petrol bakımından zengindir.","e2":"There is a wide gulf between our opinions.","e2t":"Görüşlerimiz arasında geniş bir uçurum (körfez) var."},{"w":"gum","tr":"diş eti / sakız / yapıştırıcı","te":"Noun","tt":"İsim","de":"The pink area around teeth or chewing gum","dt":"Dişlerin etrafındaki pembe alan veya çiğneme sakızı","e1":"My gums are bleeding.","e1t":"Diş etlerim kanıyor.","e2":"Do you want a piece of gum?","e2t":"Bir tane sakız ister misin?"},{"w":"gun","tr":"silah","te":"Noun/Verb","tt":"İsim/Fiil","de":"A weapon that shoots bullets","dt":"Mermi atan silah","e1":"It is illegal to carry a gun here.","e1t":"Burada silah taşımak yasa dışıdır.","e2":"The hunter cleaned his gun.","e2t":"Avcı silahını temizledi."},{"w":"guy","tr":"adam / tip (gayriresmi)","te":"Noun","tt":"İsim","de":"A man or boy (informal)","dt":"Adam veya erkek çocuk (gayriresmi)","e1":"He's a nice guy.","e1t":"O hoş bir adam.","e2":"Who is that guy?","e2t":"Şu tip (adam) kim?"},{"w":"gym","tr":"spor salonu","te":"Noun","tt":"İsim","de":"A room or building for physical exercise","dt":"Fiziksel egzersiz için oda veya bina","e1":"I go to the gym three times a week.","e1t":"Haftada üç kez spor salonuna giderim.","e2":"The school has a new gym.","e2t":"Okulun yeni bir spor salonu var."},{"w":"habit","tr":"alışkanlık","te":"Noun","tt":"İsim","de":"Something that you do often and regularly","dt":"Sık sık ve düzenli olarak yaptığınız şey","e1":"Smoking is a bad habit.","e1t":"Sigara içmek kötü bir alışkanlıktır.","e2":"I have a habit of drinking tea in the morning.","e2t":"Sabahları çay içme alışkanlığım var."},{"w":"habitat","tr":"doğal ortam / yaşam alanı","te":"Noun","tt":"İsim","de":"The natural home of an animal or plant","dt":"Bir hayvanın veya bitkinin doğal evi","e1":"The forest is the natural habitat of tigers.","e1t":"Orman, kaplanların doğal yaşam alanıdır.","e2":"We must protect their habitat.","e2t":"Onların yaşam alanlarını korumalıyız."},{"w":"hairdresser","tr":"kuaför","te":"Noun","tt":"İsim","de":"A person who cuts or styles hair","dt":"Saç kesen veya şekillendiren kişi","e1":"I am going to the hairdresser tomorrow.","e1t":"Yarın kuaföre gidiyorum.","e2":"My hairdresser does a great job.","e2t":"Kuaförüm harika bir iş çıkarıyor."},{"w":"half","tr":"yarım","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Either of two equal parts","dt":"İki eşit parçadan her biri","e1":"Cut the apple in half.","e1t":"Elmayı ikiye (yarıya) böl.","e2":"It's half past eight.","e2t":"Saat sekiz buçuk (sekizi yarım geçiyor)."},{"w":"hall","tr":"salon","te":"Noun","tt":"İsim","de":"A large room for meetings or concerts","dt":"Toplantılar veya konserler için büyük oda","e1":"The concert is in the main hall.","e1t":"Konser ana salonda.","e2":"Wait for me in the entrance hall.","e2t":"Beni giriş salonunda bekle."},{"w":"handful","tr":"avuç dolusu","te":"Noun","tt":"İsim","de":"An amount that fits in one hand","dt":"Bir ele sığan miktar","e1":"He ate a handful of nuts.","e1t":"Bir avuç dolusu kuruyemiş yedi.","e2":"There were only a handful of people at the meeting.","e2t":"Toplantıda sadece bir avuç (az sayıda) insan vardı."},{"w":"handle","tr":"idare etmek / sap","te":"Verb/Noun","tt":"Fiil/İsim","de":"To deal with or the part of an object you hold","dt":"Başa çıkmak veya bir nesnenin tutulan kısmı","e1":"Can you handle this situation?","e1t":"Bu durumu idare edebilir misin?","e2":"The door handle is broken.","e2t":"Kapı kolu (sapı) bozuk."},{"w":"handsome","tr":"yakışıklı","te":"Adjective","tt":"Sıfat","de":"Physically attractive (usually for men)","dt":"Fiziksel olarak çekici (genellikle erkekler için)","e1":"He is a very handsome man.","e1t":"O çok yakışıklı bir adam.","e2":"You look handsome in that suit.","e2t":"O takım elbise içinde yakışıklı görünüyorsun."},{"w":"hang","tr":"asmak","te":"Verb","tt":"Fiil","de":"To fasten something at the top","dt":"Bir şeyi üstten sabitlemek","e1":"Hang your coat on the hook.","e1t":"Montunu kancaya as.","e2":"There is a picture hanging on the wall.","e2t":"Duvarda asılı bir resim var."},{"w":"happen","tr":"olmak","te":"Verb","tt":"Fiil","de":"To take place or occur","dt":"Meydana gelmek veya gerçekleşmek","e1":"What happened yesterday?","e1t":"Dün ne oldu?","e2":"Accidents can happen anytime.","e2t":"Kazalar her an olabilir."},{"w":"happiness","tr":"mutluluk","te":"Noun","tt":"İsim","de":"The feeling of being happy","dt":"Mutlu olma duygusu","e1":"Money doesn't always bring happiness.","e1t":"Para her zaman mutluluk getirmez.","e2":"Her face was full of happiness.","e2t":"Yüzü mutluluk doluydu."},{"w":"harbor","tr":"liman","te":"Noun","tt":"İsim","de":"A place on the coast where ships stay","dt":"Gemilerin kaldığı sahil üzerindeki yer","e1":"The ship is entering the harbor.","e1t":"Gemi limana giriyor.","e2":"It is a very busy harbor.","e2t":"Burası çok kalabalık (işlek) bir liman."},{"w":"harbor / harbour","tr":"liman","te":"Noun/Verb","tt":"İsim/Fiil","de":"An area of water near the coast for ships","dt":"Gemiler için kıyı yakınındaki su alanı","e1":"The boat is in the harbor.","e1t":"Tekne limanda.","e2":"Istanbul has a beautiful natural harbor.","e2t":"İstanbul'un güzel bir doğal limanı vardır."},{"w":"hard","tr":"working","te":"çalışkan","tt":"Adjective","de":"Sıfat","dt":"Putting a lot of effort into a job","e1":"Bir işe çok çaba sarf eden","e1t":"He is a very hard","e2":"working student.","e2t":"O çok çalışkan bir öğrencidir."},{"w":"hardly","tr":"zar zor","te":"Adverb","tt":"Zarf","de":"Only just; almost not","dt":"Sadece; neredeyse hiç","e1":"I can hardly see without my glasses.","e1t":"Gözlüklerim olmadan zar zor görebiliyorum.","e2":"He hardly ever eats meat.","e2t":"Neredeyse hiç et yemez."},{"w":"hardware","tr":"donanım","te":"Noun","tt":"İsim","de":"The physical parts of a computer","dt":"Bilgisayarın fiziksel parçaları","e1":"I need to upgrade my computer hardware.","e1t":"Bilgisayar donanımımı yükseltmem gerekiyor.","e2":"The store sells computer hardware and software.","e2t":"Mağaza bilgisayar donanımı ve yazılımı satıyor."},{"w":"harm","tr":"zarar / zarar vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Physical injury or damage","dt":"Fiziksel yaralanma veya hasar","e1":"Smoking does great harm to your health.","e1t":"Sigara içmek sağlığınıza büyük zarar verir.","e2":"I didn't mean to harm you.","e2t":"Sana zarar vermek istememiştim."},{"w":"harmful","tr":"zararlı","te":"Adjective","tt":"Sıfat","de":"Causing harm","dt":"Zarara neden olan","e1":"Too much sun can be harmful.","e1t":"Çok fazla güneş zararlı olabilir.","e2":"These chemicals are harmful to the environment.","e2t":"Bu kimyasallar çevre için zararlıdır."},{"w":"harmony","tr":"uyum / armoni","te":"Noun","tt":"İsim","de":"A state of agreement or pleasing sounds","dt":"Anlaşma durumu veya hoş sesler","e1":"We should live in harmony with nature.","e1t":"Doğa ile uyum içinde yaşamalıyız.","e2":"The singers sang in perfect harmony.","e2t":"Şarkıcılar mükemmel bir armoni içinde söylediler."},{"w":"harvest","tr":"hasat","te":"Noun/Verb","tt":"İsim/Fiil","de":"The time when crops are gathered","dt":"Mahsullerin toplandığı zaman","e1":"It is a good harvest this year.","e1t":"Bu yıl iyi bir hasat var.","e2":"Farmers are harvesting the wheat.","e2t":"Çiftçiler buğdayı hasat ediyorlar."},{"w":"have","tr":"sahip olmak","te":"Verb","tt":"Fiil","de":"To own or possess something","dt":"Bir şeye sahip olmak","e1":"I have two sisters.","e1t":"İki kız kardeşim var.","e2":"Do you have a car?","e2t":"Araban var mı?"},{"w":"he","tr":"o (erkek)","te":"Pronoun","tt":"Zamir","de":"A male person already mentioned","dt":"Daha önce bahsedilen erkek kişi","e1":"He is a teacher.","e1t":"O bir öğretmendir.","e2":"I saw him yesterday.","e2t":"Onu dün gördüm."},{"w":"headache","tr":"baş ağrısı","te":"Noun","tt":"İsim","de":"A pain in the head","dt":"Baştaki ağrı","e1":"I have a terrible headache.","e1t":"Korkunç bir baş ağrım var.","e2":"Stress can cause headaches.","e2t":"Stres baş ağrılarına neden olabilir."},{"w":"headquarters","tr":"genel merkez","te":"Noun","tt":"İsim","de":"The main office of an organization","dt":"Bir organizasyonun ana ofisi","e1":"The company's headquarters is in New York.","e1t":"Şirketin genel merkezi New York'ta.","e2":"They are moving their headquarters to London.","e2t":"Genel merkezlerini Londra'ya taşıyorlar."},{"w":"heal","tr":"iyileşmek / iyileştirmek","te":"Verb","tt":"Fiil","de":"To become healthy again after an injury","dt":"Yaralanmadan sonra tekrar sağlıklı olmak","e1":"The wound will heal in a few days.","e1t":"Yara birkaç gün içinde iyileşecek.","e2":"Time heals all wounds.","e2t":"Zaman tüm yaraları iyileştirir."},{"w":"healthy","tr":"sağlıklı","te":"Adjective","tt":"Sıfat","de":"In good physical condition","dt":"İyi fiziksel durumda olma","e1":"Eating vegetables is healthy.","e1t":"Sebze yemek sağlıklıdır.","e2":"I want to live a healthy life.","e2t":"Sağlıklı bir hayat yaşamak istiyorum."},{"w":"hearing","tr":"işitme / duruşma","te":"Noun","tt":"İsim","de":"The sense of hearing or a legal meeting","dt":"İşitme duyusu veya yasal toplantı","e1":"He has a hearing problem.","e1t":"İşitme sorunu var.","e2":"The court hearing is next week.","e2t":"Mahkeme duruşması haftaya."},{"w":"heat","tr":"ısı / ısıtmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"High temperature or to make warm","dt":"Yüksek sıcaklık veya sıcak hale getirmek","e1":"The heat was unbearable.","e1t":"Isı dayanılmazdı.","e2":"Heat the soup, please.","e2t":"Çorbayı ısıt lütfen."},{"w":"heater","tr":"ısıtıcı","te":"Noun","tt":"İsim","de":"A device that makes a room warm","dt":"Bir odayı ısıtan cihaz","e1":"Turn on the heater, it's cold.","e1t":"Isıtıcıyı aç, hava soğuk.","e2":"The electric heater is broken.","e2t":"Elektrikli ısıtıcı bozuk."},{"w":"heating","tr":"ısıtma","te":"Noun","tt":"İsim","de":"A system for keeping a building warm","dt":"Bir binayı sıcak tutma sistemi","e1":"Central heating is common here.","e1t":"Merkezi ısıtma burada yaygındır.","e2":"Turn up the heating, it's cold.","e2t":"Isıtmayı aç, hava soğuk."},{"w":"heaven","tr":"cennet","te":"Noun","tt":"İsim","de":"A place of peace or where God lives","dt":"Huzur yeri veya Tanrı'nın yaşadığı yer","e1":"Do you believe in heaven?","e1t":"Cennete inanır mısın?","e2":"This place is a little piece of heaven.","e2t":"Burası cennetten küçük bir parça."},{"w":"heavy","tr":"ağır","te":"Adjective","tt":"Sıfat","de":"Having a lot of weight","dt":"Çok ağırlığı olan","e1":"This bag is too heavy for me.","e1t":"Bu çanta benim için çok ağır.","e2":"There was heavy rain yesterday.","e2t":"Dün şiddetli (ağır) yağmur vardı."},{"w":"heel","tr":"topuk","te":"Noun/Verb","tt":"İsim/Fiil","de":"The back part of the foot or shoe","dt":"Ayağın veya ayakkabının arka kısmı","e1":"My heels hurt.","e1t":"Topuklarım ağrıyor.","e2":"She was wearing high heels.","e2t":"Yüksek topuklu giyiyordu."},{"w":"height","tr":"boy / yükseklik","te":"Noun","tt":"İsim","de":"The measurement from top to bottom","dt":"Yukarıdan aşağıya olan ölçü","e1":"What is your height?","e1t":"Boyun kaç?","e2":"He is afraid of heights.","e2t":"Yükseklik korkusu var."},{"w":"helicopter","tr":"helikopter","te":"Noun","tt":"İsim","de":"An aircraft with large spinning blades","dt":"Büyük dönen kanatları olan hava aracı","e1":"The rescue team arrived by helicopter.","e1t":"Kurtarma ekibi helikopterle geldi.","e2":"I have never flown in a helicopter.","e2t":"Hiç helikopterle uçmadım."},{"w":"hell","tr":"cehennem","te":"Noun","tt":"İsim","de":"A place of suffering or where the devil lives","dt":"Istırap yeri veya şeytanın yaşadığı yer","e1":"War is hell.","e1t":"Savaş cehennemdir.","e2":"Go to hell!","e2t":"Cehenneme git!"},{"w":"helmet","tr":"kask / kasket","te":"Noun","tt":"İsim","de":"A hard hat used for protection","dt":"Korunma için kullanılan sert şapka","e1":"Always wear a helmet when riding a bike.","e1t":"Bisiklet sürerken her zaman kask tak.","e2":"The firemen wore protective helmets.","e2t":"İtfaiyeciler koruyucu kasklar taktı."},{"w":"helpful","tr":"yardımsever","te":"Adjective","tt":"Sıfat","de":"Willing to help others","dt":"Başkalarına yardım etmeye istekli","e1":"The staff were very helpful.","e1t":"Personel çok yardımcıydı.","e2":"Thank you for your helpful advice.","e2t":"Yardımcı tavsiyen için teşekkürler."},{"w":"hence","tr":"bu yüzden / dolayısıyla","te":"Adverb","tt":"Zarf","de":"Therefore or from this time","dt":"Bu nedenle veya bu zamandan itibaren","e1":"He is a teacher, hence his patience.","e1t":"O bir öğretmendir, bu yüzden (bundan dolayı) sabırlıdır.","e2":"Two years hence.","e2t":"Bundan iki yıl sonra."},{"w":"her","tr":"onu / ona / onun (dişi)","te":"Pronoun/Determiner","tt":"Zamir/Belirleyici","de":"Relating to a female person","dt":"Bir kadın kişiyle ilgili","e1":"I saw her yesterday.","e1t":"Onu dün gördüm.","e2":"This is her book.","e2t":"Bu onun kitabı."},{"w":"here","tr":"burada","te":"Adverb","tt":"Zarf","de":"In or to this place","dt":"Bu yerde veya bu yere","e1":"Come here, please.","e1t":"Buraya gel lütfen.","e2":"I have lived here for five years.","e2t":"Beş yıldır burada yaşıyorum."},{"w":"heritage","tr":"miras (kültürel)","te":"Noun","tt":"İsim","de":"Traditions or buildings from the past","dt":"Geçmişten gelen gelenekler veya yapılar","e1":"We must protect our cultural heritage.","e1t":"Kültürel mirasımızı korumalıyız.","e2":"Ephesus is a world heritage site.","e2t":"Efes bir dünya mirası alanıdır."},{"w":"hero","tr":"kahraman","te":"Noun","tt":"İsim","de":"A person admired for bravery","dt":"Cesareti için takdir edilen kişi","e1":"He is a national hero.","e1t":"O bir ulusal kahramandır.","e2":"My father is my hero.","e2t":"Benim kahramanım babamdır."},{"w":"hers","tr":"onunki (dişi)","te":"Pronoun","tt":"Zamir","de":"Something belonging to a female person","dt":"Bir kadın kişiye ait olan şey","e1":"This bag is hers.","e1t":"Bu çanta onunki (onun).","e2":"Is this pen yours or hers?","e2t":"Bu kalem senin mi yoksa onunki mi?"},{"w":"herself","tr":"kendisi (dişi)","te":"Pronoun","tt":"Zamir","de":"The same female person mentioned before","dt":"Daha önce bahsedilen aynı kadın kişi","e1":"She did it herself.","e1t":"Onu kendisi yaptı.","e2":"She looked at herself in the mirror.","e2t":"Aynada kendisine baktı."},{"w":"hesitate","tr":"tereddüt etmek","te":"Verb","tt":"Fiil","de":"To pause before doing something","dt":"Bir şeyi yapmadan önce duraksamak","e1":"Don't hesitate to call me.","e1t":"Beni aramaya tereddüt etme.","e2":"He hesitated for a moment.","e2t":"Bir an için tereddüt etti."},{"w":"hi","tr":"selam","te":"Interjection","tt":"Ünlem","de":"An informal greeting","dt":"Resmi olmayan selamlama","e1":"Hi! How's it going?","e1t":"Selam! Nasıl gidiyor?","e2":"Just wanted to say hi.","e2t":"Sadece bir selam vermek istedim."},{"w":"hide","tr":"saklanmak","te":"Verb","tt":"Fiil","de":"To put something where it cannot be seen","dt":"Bir şeyi görülmeyecek bir yere koymak","e1":"Where did you hide the keys?","e1t":"Anahtarları nereye sakladın?","e2":"The children are hiding in the garden.","e2t":"Çocuklar bahçede saklanıyorlar."},{"w":"high","tr":"yüksek","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"At a great distance from the ground","dt":"Yerden büyük bir mesafede","e1":"The mountain is very high.","e1t":"Dağ çok yüksektir.","e2":"The prices are getting high.","e2t":"Fiyatlar yükseliyor."},{"w":"highlight","tr":"vurgulamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To draw attention to something","dt":"Bir şeye dikkat çekmek","e1":"The report highlights the main problems.","e1t":"Rapor ana problemleri vurguluyor.","e2":"What was the highlight of your trip?","e2t":"Gezinizin en can alıcı noktası (vurgusu) neydi?"},{"w":"highly","tr":"son derece","te":"Adverb","tt":"Zarf","de":"To a high degree","dt":"Yüksek bir derecede","e1":"He is a highly respected doctor.","e1t":"O son derece saygı duyulan bir doktordur.","e2":"This is highly recommended.","e2t":"Bu şiddetle (son derece) önerilir."},{"w":"highway","tr":"otoyol","te":"Noun","tt":"İsim","de":"A main road for traveling long distances","dt":"Uzun mesafeli yolculuklar için ana yol","e1":"We drove along the highway.","e1t":"Otoyol boyunca sürdük.","e2":"The highway is closed for repairs.","e2t":"Otoyol tamir için kapalı."},{"w":"hill","tr":"tepe","te":"Noun","tt":"İsim","de":"A high area of land, smaller than a mountain","dt":"Dağdan küçük yüksek kara alanı","e1":"Our house is on the top of the hill.","e1t":"Evimiz tepenin üstündedir.","e2":"They walked up the hill.","e2t":"Tepeden yukarı yürüdüler."},{"w":"hire","tr":"işe almak / kiralamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To employ someone or pay to use something","dt":"Birini işe almak veya bir şeyi kullanmak için ödeme yapmak","e1":"We need to hire a new assistant.","e1t":"Yeni bir asistan tutmamız (işe almamız) gerekiyor.","e2":"Let's hire a car for the weekend.","e2t":"Hafta sonu için bir araba kiralayalım."},{"w":"hold","tr":"tutmak","te":"Verb","tt":"Fiil","de":"To have something in your hand","dt":"Elinizde bir şeye sahip olmak/tutmak","e1":"Hold my hand, please.","e1t":"Lütfen elimi tut.","e2":"Can you hold this for a second?","e2t":"Bunu bir saniye tutabilir misin?"},{"w":"hole","tr":"delik","te":"Noun","tt":"İsim","de":"An empty space in something solid","dt":"Katı bir şeyin içindeki boşluk","e1":"There is a hole in my sock.","e1t":"Çorabımda bir delik var.","e2":"Rabbits live in holes.","e2t":"Tavşanlar deliklerde yaşar."},{"w":"hometown","tr":"memleket","te":"Noun","tt":"İsim","de":"The town where you were born or grew up","dt":"Doğduğunuz veya büyüdüğünüz kasaba","e1":"I am visiting my hometown next week.","e1t":"Gelecek hafta memleketimi ziyaret ediyorum.","e2":"Izmir is my hometown.","e2t":"İzmir benim memleketimdir."},{"w":"honest","tr":"dürüst","te":"Adjective","tt":"Sıfat","de":"Telling the truth","dt":"Doğruyu söyleyen","e1":"Be honest with me.","e1t":"Bana karşı dürüst ol.","e2":"He is an honest businessman.","e2t":"O dürüst bir iş adamıdır."},{"w":"honey","tr":"bal","te":"Noun","tt":"İsim","de":"A sweet liquid made by bees","dt":"Arılar tarafından yapılan tatlı sıvı","e1":"I like honey with my tea.","e1t":"Çayımla balı severim.","e2":"Bees produce honey.","e2t":"Arılar bal üretir."},{"w":"hope","tr":"umut etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To want something to happen","dt":"Bir şeyin olmasını istemek","e1":"I hope you win the match.","e1t":"Maçı kazanmanı umuyorum.","e2":"Don't lose hope.","e2t":"Umudunu kaybetme."},{"w":"host","tr":"ev sahibi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who receives guests","dt":"Misafir ağırlayan kişi","e1":"Our host was very welcoming.","e1t":"Ev sahibimiz çok misafirperverdi.","e2":"Brazil will host the next conference.","e2t":"Bir sonraki konferansa Brezilya ev sahipliği yapacak."},{"w":"huge","tr":"çok büyük","te":"Adjective","tt":"Sıfat","de":"Extremely large in size or amount","dt":"Boyut veya miktar olarak son derece büyük","e1":"He lives in a huge house.","e1t":"Devasa bir evde yaşıyor.","e2":"There was a huge crowd.","e2t":"Çok büyük bir kalabalık vardı."},{"w":"human","tr":"insan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person or relating to people","dt":"Bir kişi veya insanlarla ilgili","e1":"We are all human.","e1t":"Hepimiz insanız.","e2":"Human rights are very important.","e2t":"İnsan hakları çok önemlidir."},{"w":"humor","tr":"mizah","te":"Noun","tt":"İsim","de":"The quality of being funny","dt":"Komik olma özelliği","e1":"He has a great sense of humor.","e1t":"Harika bir mizah anlayışı var.","e2":"I like British humor.","e2t":"İngiliz mizahını severim."},{"w":"hunt","tr":"avlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To chase and kill wild animals","dt":"Vahşi hayvanları kovalamak ve öldürmek","e1":"Lions hunt other animals.","e1t":"Aslanlar diğer hayvanları avlar.","e2":"They are going on a hunt.","e2t":"Bir ava gidiyorlar."},{"w":"hurry","tr":"acele etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move or do something quickly","dt":"Hızlıca hareket etmek veya bir şey yapmak","e1":"Hurry up, we are late!","e1t":"Acele et, geç kaldık!","e2":"I am in a hurry.","e2t":"Acelem var."},{"w":"hurt","tr":"incinmek / acımak","te":"Verb/Adjective","tt":"To cause physical pain or to feel pain","de":"Fiziksel acıya neden olmak veya acı hissetmek","dt":"My leg hurts.","e1":"Bacağım ağrıyor (acıyor).","e1t":"Did you hurt yourself?","e2":"Kendini incittin mi?","e2t":""},{"w":"ice","tr":"buz","te":"Noun","tt":"İsim","de":"Frozen water","dt":"Donmuş su","e1":"Put some ice in my drink.","e1t":"İçeceğime biraz buz koy.","e2":"The road is covered with ice.","e2t":"Yol buzla kaplı."},{"w":"identify","tr":"tanımlamak / teşhis etmek","te":"Verb","tt":"Fiil","de":"To recognize who or what someone or something is","dt":"Birinin veya bir şeyin kim/ne olduğunu tanımak","e1":"Can you identify this man?","e1t":"Bu adamı teşhis edebilir misin?","e2":"Scientists identified a new virus.","e2t":"Bilim insanları yeni bir virüs tanımladılar."},{"w":"immigrant","tr":"göçmen","te":"Noun","tt":"İsim","de":"A person who comes to live in a foreign country","dt":"Yabancı bir ülkede yaşamaya gelen kişi","e1":"Many immigrants live in New York.","e1t":"New York'ta birçok göçmen yaşıyor.","e2":"He is an immigrant from Italy.","e2t":"O İtalya'dan gelen bir göçmendir."},{"w":"impact","tr":"etki","te":"Noun/Verb","tt":"İsim/Fiil","de":"A powerful effect","dt":"Güçlü bir etki","e1":"The news had a big impact on her.","e1t":"Haberlerin onun üzerinde büyük bir etkisi oldu.","e2":"How will this change impact our lives?","e2t":"Bu değişiklik hayatlarımızı nasıl etkileyecek?"},{"w":"importance","tr":"önem","te":"Noun","tt":"İsim","de":"The state or fact of being of great value","dt":"Büyük değer taşıma durumu veya gerçeği","e1":"He understands the importance of education.","e1t":"Eğitimin önemini anlıyor.","e2":"This is a matter of great importance.","e2t":"Bu çok önemli bir mesele."},{"w":"impossible","tr":"imkansız","te":"Adjective","tt":"Sıfat","de":"Not able to occur, exist, or be done","dt":"Gerçekleşmesi, var olması veya yapılması mümkün olmayan","e1":"Nothing is impossible.","e1t":"Hiçbir şey imkansız değildir.","e2":"It is impossible to please everyone.","e2t":"Herkesi memnun etmek imkansızdır."},{"w":"improve","tr":"geliştirmek","te":"Verb","tt":"Fiil","de":"To make or become better","dt":"Daha iyi hale getirmek veya gelmek","e1":"I want to improve my English speaking.","e1t":"İngilizce konuşmamı geliştirmek istiyorum.","e2":"The weather is starting to improve.","e2t":"Hava düzelmeye (iyileşmeye) başlıyor."},{"w":"include","tr":"dahil etmek","te":"Verb","tt":"Fiil","de":"To contain as part of a whole","dt":"Bir bütünün parçası olarak içermek","e1":"Does the price include breakfast?","e1t":"Fiyat kahvaltıyı içeriyor mu?","e2":"Please include your phone number in the form.","e2t":"Lütfen forma telefon numaranızı dahil edin."},{"w":"increase","tr":"artırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become or make greater in size or amount","dt":"Boyut veya miktar olarak büyümek veya büyütmek","e1":"The population is increasing rapidly.","e1t":"Nüfus hızla artıyor.","e2":"We need to increase our sales.","e2t":"Satışlarımızı artırmamız gerekiyor."},{"w":"independent","tr":"bağımsız","te":"Adjective","tt":"Sıfat","de":"Not influenced or controlled by others","dt":"Başkalarından etkilenmeyen veya kontrol edilmeyen","e1":"She is a very independent woman.","e1t":"O çok bağımsız bir kadındır.","e2":"India became independent in 1947.","e2t":"Hindistan 1947'de bağımsız oldu."},{"w":"index","tr":"dizin","te":"Noun","tt":"İsim","de":"An alphabetical list of names or subjects","dt":"İsimlerin veya konuların alfabetik listesi","e1":"Look at the index at the back of the book.","e1t":"Kitabın sonundaki dizine bak.","e2":"The price index is rising.","e2t":"Fiyat endeksi yükseliyor."},{"w":"indicate","tr":"belirtmek","te":"Verb","tt":"Fiil","de":"To point out or show something","dt":"Bir şeyi işaret etmek veya göstermek","e1":"Research indicates that exercise is good.","e1t":"Araştırmalar egzersizin iyi olduğunu gösteriyor.","e2":"Please indicate your choice.","e2t":"Lütfen seçiminizi belirtin."},{"w":"industry","tr":"endüstri","te":"Noun","tt":"İsim","de":"Economic activity concerned with goods","dt":"Mallarla ilgili ekonomik faaliyet","e1":"He works in the tourism industry.","e1t":"Turizm endüstrisinde çalışıyor.","e2":"The movie industry is growing.","e2t":"Film endüstrisi büyüyor."},{"w":"infection","tr":"enfeksiyon","te":"Noun","tt":"İsim","de":"The process of infecting or being infected","dt":"Enfekte olma veya enfekte etme süreci","e1":"He has a throat infection.","e1t":"Boğaz enfeksiyonu var.","e2":"Wash your hands to prevent infection.","e2t":"Enfeksiyonu önlemek için ellerini yıka."},{"w":"influence","tr":"etki","te":"Noun/Verb","tt":"İsim/Fiil","de":"The capacity to have an effect on someone","dt":"Birinin üzerinde etki bırakma kapasitesi","e1":"My father had a great influence on me.","e1t":"Babamın üzerimde büyük bir etkisi vardı.","e2":"Don't let him influence your decision.","e2t":"Kararını etkilemesine izin verme."},{"w":"informal","tr":"resmi olmayan","te":"Adjective","tt":"Sıfat","de":"Relaxed, friendly, or unofficial","dt":"Rahat, arkadaşça veya resmi olmayan","e1":"We had an informal meeting.","e1t":"Resmi olmayan bir toplantı yaptık.","e2":"This is an informal party.","e2t":"Bu gayri resmi (rahat) bir parti."},{"w":"information","tr":"bilgi","te":"Noun","tt":"İsim","de":"Facts provided or learned about something","dt":"Bir şey hakkında sağlanan veya öğrenilen gerçekler","e1":"I need more information about the hotel.","e1t":"Otel hakkında daha fazla bilgiye ihtiyacım var.","e2":"Where is the information desk?","e2t":"Danışma (bilgi) masası nerede?"},{"w":"ingredient","tr":"içerik","te":"Noun","tt":"İsim","de":"One of the things in a mixture (food)","dt":"Bir karışımdaki (yemekteki) şeylerden biri","e1":"What are the ingredients for this cake?","e1t":"Bu kekin malzemeleri neler?","e2":"Use fresh ingredients for cooking.","e2t":"Yemek pişirmek için taze malzemeler kullan."},{"w":"initial","tr":"ilk","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Existing or occurring at the beginning","dt":"Başlangıçta var olan veya gerçekleşen","e1":"My initial reaction was surprise.","e1t":"İlk tepkim şaşkınlıktı.","e2":"Write your initials here.","e2t":"Buraya isminizin baş harflerini yazın."},{"w":"injure","tr":"yaralamak","te":"Verb","tt":"Fiil","de":"To cause physical harm to someone","dt":"Birine fiziksel zarar vermek","e1":"He injured his leg during the match.","e1t":"Maç sırasında bacağını yaraladı.","e2":"Be careful not to injure yourself.","e2t":"Kendini yaralamamaya dikkat et."},{"w":"injury","tr":"yaralanma","te":"Noun","tt":"İsim","de":"Physical harm or damage to the body","dt":"Vücuda gelen fiziksel zarar veya hasar","e1":"He has a serious head injury.","e1t":"Ciddi bir kafa yaralanması var.","e2":"There were no injuries in the accident.","e2t":"Kazada yaralanan olmadı."},{"w":"ink","tr":"mürekkep","te":"Noun","tt":"İsim","de":"Colored liquid used for writing","dt":"Yazı yazmak için kullanılan renkli sıvı","e1":"My pen has blue ink.","e1t":"Kalemimin mavi mürekkebi var.","e2":"Black ink.","e2t":"Siyah mürekkep."},{"w":"insect","tr":"böcek","te":"Noun","tt":"İsim","de":"A small animal with six legs","dt":"Altı bacaklı küçük hayvan","e1":"I am afraid of insects.","e1t":"Böceklerden korkarım.","e2":"Ants and bees are insects.","e2t":"Karıncalar ve arılar böcektir."},{"w":"insist","tr":"ısrar etmek","te":"Verb","tt":"Fiil","de":"To demand something forcefully","dt":"Bir şeyi zorla talep etmek","e1":"I insist that you take this gift.","e1t":"Bu hediyeyi almanı ısrar ediyorum.","e2":"He insisted on paying the bill.","e2t":"Hesabı ödemekte ısrar etti."},{"w":"instead","tr":"yerine","te":"Adverb","tt":"Zarf","de":"In place of something else","dt":"Başka bir şeyin yerine","e1":"I'll have tea instead of coffee.","e1t":"Kahve yerine çay alacağım.","e2":"If you can't go, I'll go instead.","e2t":"Eğer sen gidemezsen, yerine ben giderim."},{"w":"instruction","tr":"talimat","te":"Noun","tt":"İsim","de":"Detailed information about how to do something","dt":"Bir şeyin nasıl yapılacağına dair detaylı bilgi","e1":"Read the instructions before you start.","e1t":"Başlamadan önce talimatları oku.","e2":"Follow the teacher's instructions.","e2t":"Öğretmenin talimatlarını takip et."},{"w":"instructor","tr":"eğitmen","te":"Noun","tt":"İsim","de":"A person who teaches a skill","dt":"Bir beceriyi öğreten kişi","e1":"He is a driving instructor.","e1t":"O bir direksiyon eğitmenidir.","e2":"Ask the instructor for help.","e2t":"Eğitmenden yardım iste."},{"w":"instrument","tr":"enstrüman","te":"Noun","tt":"İsim","de":"A tool or device for music or work","dt":"Müzik veya iş için kullanılan araç veya cihaz","e1":"Do you play a musical instrument?","e1t":"Bir müzik enstrümanı çalıyor musun?","e2":"The dentist used a small instrument.","e2t":"Diş hekimi küçük bir alet (enstrüman) kullandı."},{"w":"insult","tr":"hakaret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A disrespectful or abusive remark","dt":"Saygısız veya aşağılayıcı söz","e1":"His comments were an insult to me.","e1t":"Onun yorumları benim için bir hakaretti.","e2":"Don't insult people.","e2t":"İnsanlara hakaret etme."},{"w":"insurance","tr":"sigorta","te":"Noun","tt":"İsim","de":"A practice of providing protection against loss","dt":"Kayıplara karşı koruma sağlama uygulaması","e1":"Do you have car insurance?","e1t":"Araba sigortan var mı?","e2":"Health insurance is very expensive.","e2t":"Sağlık sigortası çok pahalı."},{"w":"intelligence","tr":"zeka","te":"Noun","tt":"İsim","de":"The ability to learn and understand things","dt":"Bir şeyleri öğrenme ve anlama yeteneği","e1":"Artificial intelligence is changing the world.","e1t":"Yapay zeka dünyayı değiştiriyor.","e2":"He is a man of great intelligence.","e2t":"O büyük bir zekaya sahip bir adam."},{"w":"intelligent","tr":"zeki","te":"Adjective","tt":"Sıfat","de":"Able to learn and understand things easily","dt":"Bir şeyleri kolayca öğrenip anlayabilen","e1":"She is a very intelligent student.","e1t":"O çok zeki bir öğrencidir.","e2":"Dolphins are intelligent animals.","e2t":"Yunuslar zeki hayvanlardır."},{"w":"intention","tr":"niyet","te":"Noun","tt":"İsim","de":"An aim or plan","dt":"Bir amaç veya plan","e1":"I have no intention of leaving.","e1t":"Ayrılmaya niyetim yok.","e2":"What is your real intention?","e2t":"Gerçek niyetin ne?"},{"w":"interest","tr":"ilgi","te":"Noun/Verb","tt":"İsim/Fiil","de":"The feeling of wanting to know about something","dt":"Bir şey hakkında bilgi sahibi olma isteği","e1":"I have a great interest in history.","e1t":"Tarihe büyük bir ilgim var.","e2":"Bank interest rates are low.","e2t":"Banka faiz (ilgi) oranları düşük."},{"w":"interested","tr":"ilgili","te":"Adjective","tt":"Sıfat","de":"Feeling or showing curiosity","dt":"Merak duyma veya gösterme","e1":"I am interested in photography.","e1t":"Fotoğrafçılıkla ilgiliyim.","e2":"Are you interested in this job?","e2t":"Bu işle ilgileniyor musun?"},{"w":"interesting","tr":"ilginç","te":"Adjective","tt":"Sıfat","de":"Holding the attention; arousing curiosity","dt":"Dikkati tutan; merak uyandıran","e1":"This is a very interesting book.","e1t":"Bu çok ilginç bir kitap.","e2":"He told us an interesting story.","e2t":"Bize ilginç bir hikaye anlattı."},{"w":"interview","tr":"mülakat","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal meeting to ask questions","dt":"Soru sormak için yapılan resmi toplantı","e1":"I have a job interview tomorrow.","e1t":"Yarın bir iş görüşmem (mülakatım) var.","e2":"The journalist interviewed the artist.","e2t":"Gazeteci sanatçıyla röportaj yaptı."},{"w":"introduce","tr":"tanıtmak","te":"Verb","tt":"Fiil","de":"To make someone known by name to another","dt":"Birini başkasına ismiyle tanıtmak","e1":"Let me introduce you to my friend.","e1t":"Seni arkadaşımla tanıştırayım.","e2":"He introduced a new system.","e2t":"Yeni bir sistem sundu (tanıttı)."},{"w":"introduction","tr":"giriş","te":"Noun","tt":"İsim","de":"The beginning part of a book or talk","dt":"Bir kitabın veya konuşmanın başlangıç kısmı","e1":"Read the introduction of the book.","e1t":"Kitabın giriş kısmını oku.","e2":"He gave a short introduction.","e2t":"Kısa bir giriş yaptı."},{"w":"invent","tr":"icat etmek","te":"Verb","tt":"Fiil","de":"To create something for the first time","dt":"Bir şeyi ilk kez yaratmak","e1":"Graham Bell invented the telephone.","e1t":"Graham Bell telefonu icat etti.","e2":"He likes to invent new games.","e2t":"Yeni oyunlar icat etmeyi sever."},{"w":"invention","tr":"icat","te":"Noun","tt":"İsim","de":"Something that has been created for the first time","dt":"İlk kez yaratılan bir şey","e1":"The wheel was a great invention.","e1t":"Tekerlek harika bir icattı.","e2":"What is the most useful invention?","e2t":"En kullanışlı icat hangisidir?"},{"w":"invitation","tr":"davetiye","te":"Noun","tt":"İsim","de":"A written or spoken request to an event","dt":"Bir etkinliğe yapılan yazılı veya sözlü talep","e1":"Thank you for the invitation.","e1t":"Davet için teşekkürler.","e2":"I received a wedding invitation.","e2t":"Bir düğün davetiyesi aldım."},{"w":"involve","tr":"dahil etmek","te":"Verb","tt":"Fiil","de":"To include or affect someone or something","dt":"Birini veya bir şeyi dahil etmek veya etkilemek","e1":"The project involves a lot of work.","e1t":"Proje çok fazla iş içeriyor (dahil ediyor).","e2":"Don't involve me in your problems.","e2t":"Beni sorunlarına dahil etme."},{"w":"iron","tr":"demir / ütü / ütülemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong, hard magnetic silvery","dt":"gray metal; or a tool for smoothing clothes","e1":"Sert bir metal; veya giysileri düzeltmek için kullanılan araç","e1t":"The gate is made of iron.","e2":"Kapı demirden yapılmıştır.","e2t":"I need to iron my shirt."},{"w":"item","tr":"madde","te":"Noun","tt":"İsim","de":"An individual thing as part of a list","dt":"Bir listenin parçası olan bireysel şey","e1":"Please check every item on the list.","e1t":"Lütfen listedeki her maddeyi kontrol edin.","e2":"I bought three items at the shop.","e2t":"Dükkandan üç parça (madde) aldım."},{"w":"jealous","tr":"kıskanç","te":"Adjective","tt":"Sıfat","de":"Feeling or showing envy of someone","dt":"Birine karşı gıpta veya kıskançlık hissetme","e1":"Why are you so jealous?","e1t":"Neden bu kadar kıskançsın?","e2":"He is jealous of his brother's success.","e2t":"Kardeşinin başarısını kıskanıyor."},{"w":"jeans","tr":"kot pantolon","te":"Noun","tt":"İsim (Plural)","de":"Trousers made of blue cotton material","dt":"Mavi pamuklu kumaştan yapılmış pantolon","e1":"I am wearing blue jeans.","e1t":"Mavi kot pantolon giyiyorum.","e2":"New jeans.","e2t":"Yeni kot."},{"w":"join","tr":"katılmak / birleştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To connect or fasten things together; or to become a member","dt":"Şeyleri birbirine bağlamak; veya bir gruba üye olmak","e1":"Join our club.","e1t":"Kulübümüze katıl.","e2":"Join the two pieces.","e2t":"İki parçayı birleştir."},{"w":"journalist","tr":"gazeteci","te":"Noun","tt":"İsim","de":"A person who writes for newspapers or TV","dt":"Gazeteler veya TV için yazan kişi","e1":"He wants to be a journalist.","e1t":"Gazeteci olmak istiyor.","e2":"The journalist asked many questions.","e2t":"Gazeteci birçok soru sordu."},{"w":"journey","tr":"yolculuk","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act of traveling from one place to another","dt":"Bir yerden başka bir yere seyahat etme eylemi","e1":"It was a long and tiring journey.","e1t":"Uzun ve yorucu bir yolculuktu.","e2":"Have a safe journey!","e2t":"İyi yolculuklar!"},{"w":"judge","tr":"yargıç / yargılamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who decides cases in a court","dt":"Mahkemede davalara karar veren kişi veya yargılamak","e1":"The judge decided the case.","e1t":"Yargıç davaya karar verdi.","e2":"Don't judge a book by its cover.","e2t":"Bir kitabı kapağına göre yargılama."},{"w":"junior","tr":"kıdemsiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"For young people or lower in rank","dt":"Gençler için veya rütbece daha düşük","e1":"He is a junior developer.","e1t":"O kıdemsiz (başlangıç seviyesi) bir geliştiricidir.","e2":"My son is a junior member of the club.","e2t":"Oğlum kulübün genç bir üyesidir."},{"w":"kangaroo","tr":"kanguru","te":"Noun","tt":"İsim","de":"An Australian animal that jumps","dt":"Avustralya'ya özgü zıplayan hayvan","e1":"The kangaroo has a big tail.","e1t":"Kangurunun büyük bir kuyruğu var.","e2":"A jumping kangaroo.","e2t":"Zıplayan bir kanguru."},{"w":"keen","tr":"istekli","te":"Adjective","tt":"Sıfat","de":"Very interested or enthusiastic","dt":"Çok ilgili veya hevesli","e1":"He is keen on playing football.","e1t":"Futbol oynamaya çok meraklı (istekli).","e2":"She is a keen student.","e2t":"O hevesli bir öğrencidir."},{"w":"keep","tr":"tutmak / devam etmek","te":"Verb","tt":"Fiil","de":"To continue to have or do something","dt":"Bir şeye sahip olmaya veya yapmaya devam etmek","e1":"Keep the change, please.","e1t":"Üstü kalsın (tut), lütfen.","e2":"Keep working hard.","e2t":"Sıkı çalışmaya devam et."},{"w":"key","tr":"anahtar","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A piece of metal to open locks or very important","dt":"Kilitleri açan metal parça veya çok önemli","e1":"I lost my house keys.","e1t":"Ev anahtarlarımı kaybettim.","e2":"Education is the key to success.","e2t":"Eğitim başarının anahtarıdır."},{"w":"kick","tr":"tekme atmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit something with your foot","dt":"Bir şeye ayağınızla vurmak","e1":"He kicked the ball hard.","e1t":"Topa sertçe tekme attı.","e2":"The horse gave a sudden kick.","e2t":"At aniden bir tekme savurdu."},{"w":"kill","tr":"öldürmek","te":"Verb","tt":"Fiil","de":"To cause the death of a person or animal","dt":"Bir kişinin veya hayvanın ölümüne neden olmak","e1":"Smoking kills.","e1t":"Sigara öldürür.","e2":"Don't kill the spider.","e2t":"Örümceği öldürme."},{"w":"kind","tr":"nazik / tür","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Friendly and helpful or a type of something","dt":"Arkadaşça ve yardımsever veya bir şeyin türü","e1":"Thank you for your kind words.","e1t":"Nazik sözlerin için teşekkürler.","e2":"What kind of music do you like?","e2t":"Ne tür müzik seversin?"},{"w":"king","tr":"kral","te":"Noun","tt":"İsim","de":"A male ruler of a country","dt":"Bir ülkenin erkek yöneticisi","e1":"The king lives in a large palace.","e1t":"Kral büyük bir sarayda yaşıyor.","e2":"He was the king of England.","e2t":"O, İngiltere kralıydı."},{"w":"kite","tr":"uçurtma","te":"Noun","tt":"İsim","de":"A toy made of paper that flies in the wind","dt":"Rüzgarda uçan kağıttan oyuncak","e1":"Let's fly a kite.","e1t":"Haydi uçurtma uçuralım.","e2":"A colorful kite.","e2t":"Renkli bir uçurtma."},{"w":"knee","tr":"diz","te":"Noun","tt":"İsim","de":"The joint between the top and bottom of the leg","dt":"Bacağın üst ve alt kısmı arasındaki eklem","e1":"I hurt my knee while playing football.","e1t":"Futbol oynarken dizimi incittim.","e2":"She fell on her knees.","e2t":"Dizlerinin üzerine çöktü."},{"w":"knock","tr":"kapıya vurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit a door with your hand to get attention","dt":"Dikkat çekmek için kapıya elle vurmak","e1":"Someone is knocking on the door.","e1t":"Birisi kapıyı çalıyor (kapıya vuruyor).","e2":"I heard a loud knock.","e2t":"Sert bir vurma sesi duydum."},{"w":"knowledge","tr":"bilgi","te":"Noun","tt":"İsim","de":"Understanding or information about a subject","dt":"Bir konu hakkında anlama veya bilgi","e1":"He has a deep knowledge of history.","e1t":"Derin bir tarih bilgisine sahip.","e2":"Knowledge is power.","e2t":"Bilgi güçtür."},{"w":"lack","tr":"eksiklik","te":"Noun/Verb","tt":"İsim/Fiil","de":"Not having enough of something","dt":"Bir şeyin yeterince olmaması","e1":"The project failed due to a lack of money.","e1t":"Proje para eksikliği nedeniyle başarısız oldu.","e2":"He lacks experience.","e2t":"Onun tecrübesi eksik."},{"w":"lady","tr":"hanım","te":"Noun","tt":"İsim","de":"A polite way of talking about a woman","dt":"Bir kadın hakkında konuşmanın nazik yolu","e1":"She is a very kind lady.","e1t":"O çok nazik bir hanımefendidir.","e2":"Ladies and gentlemen, welcome!","e2t":"Hanımlar ve beyler, hoş geldiniz!"},{"w":"land","tr":"kara / arazi / iniş yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The part of the earth's surface that is not covered by water","dt":"Dünyanın sularla kaplı olmayan kısmı","e1":"They own a lot of land.","e1t":"Onların çok fazla arazisi var.","e2":"The plane will land soon.","e2t":"Uçak yakında inecek."},{"w":"landscape","tr":"manzara","te":"Noun","tt":"İsim","de":"Everything you can see in an area of land","dt":"Bir arazi alanında görebileceğiniz her şey","e1":"The landscape is beautiful in spring.","e1t":"Baharda manzara çok güzeldir.","e2":"He likes painting landscapes.","e2t":"Manzara resimleri yapmayı sever."},{"w":"language","tr":"dil","te":"Noun","tt":"İsim","de":"The system of communication used by people","dt":"İnsanlar tarafından kullanılan iletişim sistemi","e1":"How many languages can you speak?","e1t":"Kaç dil konuşabiliyorsun?","e2":"English is a global language.","e2t":"İngilizce küresel bir dildir."},{"w":"laugh","tr":"gülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a sound showing that you are happy","dt":"Mutlu olduğunuzu gösteren bir ses çıkarmak","e1":"The joke made everyone laugh.","e1t":"Şaka herkesi güldürdü.","e2":"She has a beautiful laugh.","e2t":"Güzel bir gülüşü var."},{"w":"law","tr":"hukuk / yasa","te":"Noun","tt":"İsim","de":"The system of rules of a country","dt":"Bir ülkenin kurallar sistemi","e1":"You must follow the law.","e1t":"Yasalara uymak zorundasın.","e2":"He is studying law at university.","e2t":"Üniversitede hukuk okuyor."},{"w":"lawyer","tr":"avukat","te":"Noun","tt":"İsim","de":"A person whose job is to advise about the law","dt":"İşi hukuk hakkında tavsiye vermek olan kişi","e1":"I need to talk to my lawyer.","e1t":"Avukatımla konuşmam gerekiyor.","e2":"She wants to be a successful lawyer.","e2t":"Başarılı bir avukat olmak istiyor."},{"w":"layer","tr":"katman","te":"Noun","tt":"İsim","de":"A level of material that covers a surface","dt":"Bir yüzeyi kaplayan malzeme seviyesi","e1":"Put another layer of paint on the wall.","e1t":"Duvara bir kat daha boya sür.","e2":"The cake has three layers.","e2t":"Kekin üç katmanı (katı) var."},{"w":"lazy","tr":"tembel","te":"Adjective","tt":"Sıfat","de":"Not wanting to work or use energy","dt":"Çalışmak veya enerji harcamak istemeyen","e1":"Don't be so lazy, get up!","e1t":"Bu kadar tembel olma, kalk!","e2":"He is a lazy student.","e2t":"O tembel bir öğrencidir."},{"w":"lead","tr":"liderlik etmek","te":"Verb","tt":"Fiil","de":"To show the way or be in charge","dt":"Yolu göstermek veya sorumlu olmak","e1":"You lead the way, and we will follow.","e1t":"Sen yolu göster (liderlik et), biz takip ederiz.","e2":"Who will lead the project?","e2t":"Projeye kim liderlik edecek?"},{"w":"leader","tr":"lider","te":"Noun","tt":"İsim","de":"A person in control of a group or country","dt":"Bir grubun veya ülkenin kontrolünü elinde tutan kişi","e1":"He is a great leader.","e1t":"O harika bir liderdir.","e2":"Who is the leader of the party?","e2t":"Partinin lideri kim?"},{"w":"leaf","tr":"yaprak","te":"Noun","tt":"İsim","de":"The green part of a plant or tree","dt":"Bir bitkinin veya ağacın yeşil kısmı","e1":"The leaves are falling in autumn.","e1t":"Sonbaharda yapraklar düşüyor.","e2":"Look at this green leaf.","e2t":"Bu yeşil yaprağa bak."},{"w":"learn","tr":"öğrenmek","te":"Verb","tt":"Fiil","de":"To gain knowledge or skill","dt":"Bilgi veya beceri kazanmak","e1":"I want to learn how to drive.","e1t":"Araba sürmeyi öğrenmek istiyorum.","e2":"Children learn very fast.","e2t":"Çocuklar çok hızlı öğrenir."},{"w":"leather","tr":"deri","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Material made from the skin of animals","dt":"Hayvan derisinden yapılan malzeme","e1":"This jacket is made of leather.","e1t":"Bu ceket deriden yapılmış.","e2":"I bought a leather bag.","e2t":"Deri bir çanta aldım."},{"w":"lecture","tr":"ders / konferans","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal talk on a subject to a group","dt":"Bir gruba bir konu hakkında yapılan resmi konuşma","e1":"I have a history lecture at 10 AM.","e1t":"Sabah 10'da tarih dersim var.","e2":"The professor lectured about science.","e2t":"Profesör bilim hakkında ders verdi."},{"w":"legal","tr":"yasal","te":"Adjective","tt":"Sıfat","de":"Relating to or allowed by the law","dt":"Yasayla ilgili olan veya yasanın izin verdiği","e1":"Is it legal to park here?","e1t":"Buraya park etmek yasal mı?","e2":"You should seek legal advice.","e2t":"Yasal tavsiye almalısın."},{"w":"lend","tr":"ödünç vermek","te":"Verb","tt":"Fiil","de":"To give something for a short time","dt":"Bir şeyi kısa süreliğine vermek","e1":"Can you lend me your pen?","e1t":"Kalemini bana ödünç verebilir misin?","e2":"I lent him ten dollars.","e2t":"Ona on dolar ödünç verdim."},{"w":"less","tr":"daha az","te":"Adjective/Adverb/Determiner","tt":"A smaller amount of","de":"Bir şeyin daha küçük miktarı","dt":"Eat less sugar.","e1":"Daha az şeker ye.","e1t":"Less than ten.","e2":"Ondan az.","e2t":""},{"w":"level","tr":"seviye","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The height or position of something","dt":"Bir şeyin yüksekliği veya konumu","e1":"My English level is A2.","e1t":"İngilizce seviyem A2.","e2":"This road is perfectly level.","e2t":"Bu yol tamamen düzdür (seviyelidir)."},{"w":"license","tr":"lisans / ehliyet","te":"Noun","tt":"İsim","de":"An official document that gives permission","dt":"İzin veren resmi bir belge","e1":"I finally got my driving license.","e1t":"Sonunda ehliyetimi (sürüş lisansımı) aldım.","e2":"Do you have a business license?","e2t":"İşletme ruhsatınız var mı?"},{"w":"lie","tr":"yalan söylemek / uzanmak / yalan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say something that is not true; or to rest in a flat position","dt":"Doğru olmayan şeyi söylemek; veya yere uzanmak","e1":"Don't tell a lie.","e1t":"Yalan söyleme.","e2":"Lie down on the bed.","e2t":"Yatağa uzan."},{"w":"lift","tr":"kaldırmak / asansör","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something up or a machine for floors","dt":"Bir şeyi yukarı hareket ettirmek veya katlar arası taşıyan makine","e1":"Can you help me lift this box?","e1t":"Bu kutuyu kaldırmama yardım edebilir misin?","e2":"Take the lift to the fourth floor.","e2t":"Dördüncü kata asansörle çık."},{"w":"light","tr":"hafif / ışık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Brightness or not heavy","dt":"Aydınlık veya ağır olmayan","e1":"Turn on the light, please.","e1t":"Lütfen ışığı yak.","e2":"This bag is very light.","e2t":"Bu çanta çok hafif."},{"w":"likely","tr":"muhtemel","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Probable or expected to happen","dt":"Olası veya olması beklenen","e1":"It is likely to rain today.","e1t":"Bugün yağmur yağması muhtemel.","e2":"That is the most likely solution.","e2t":"Bu en muhtemel çözümdür."},{"w":"limit","tr":"sınır","te":"Noun/Verb","tt":"İsim/Fiil","de":"The greatest amount or level allowed","dt":"İzin verilen en büyük miktar veya seviye","e1":"What is the speed limit?","e1t":"Hız sınırı nedir?","e2":"You must limit your spending.","e2t":"Harcamalarını sınırlamalısın."},{"w":"link","tr":"bağlantı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A connection between two things","dt":"İki şey arasındaki bağlantı","e1":"Click on the link to see the photo.","e1t":"Fotoğrafı görmek için bağlantıya (linke) tıkla.","e2":"The two crimes are linked.","e2t":"İki suç birbirine bağlı."},{"w":"lion","tr":"aslan","te":"Noun","tt":"İsim","de":"A big wild cat","dt":"Büyük vahşi kedi","e1":"The lion is the king of the jungle.","e1t":"Aslan ormanların kralıdır.","e2":"A strong lion.","e2t":"Güçlü bir aslan."},{"w":"list","tr":"liste","te":"Noun/Verb","tt":"İsim/Fiil","de":"A set of names or items written down","dt":"Yazılmış isimler veya maddeler seti","e1":"Make a shopping list.","e1t":"Alışveriş listesi yap.","e2":"My name is not on the list.","e2t":"İsmim listede değil."},{"w":"literature","tr":"edebiyat","te":"Noun","tt":"İsim","de":"Written works such as novels and poems","dt":"Romanlar ve şiirler gibi yazılı eserler","e1":"He is studying English literature.","e1t":"İngiliz edebiyatı okuyor.","e2":"I like classic literature.","e2t":"Klasik edebiyatı severim."},{"w":"lizard","tr":"kertenkele","te":"Noun","tt":"İsim","de":"A small reptile with a long tail","dt":"Uzun kuyruklu küçük sürüngen","e1":"There is a lizard in the garden.","e1t":"Bahçede bir kertenkele var.","e2":"A small lizard.","e2t":"Küçük bir kertenkele."},{"w":"local","tr":"yerel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a particular area","dt":"Belirli bir alanla ilgili olan","e1":"I buy vegetables from the local market.","e1t":"Sebzeleri yerel marketten alırım.","e2":"The local people are very friendly.","e2t":"Yerel halk çok arkadaş canlısı."},{"w":"location","tr":"konum","te":"Noun","tt":"İsim","de":"A particular place or position","dt":"Belirli bir yer veya konum","e1":"The hotel is in a great location.","e1t":"Otel harika bir konumdadır.","e2":"Send me your location, please.","e2t":"Lütfen bana konumunu gönder."},{"w":"lock","tr":"kilitlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fasten with a key","dt":"Anahtar ile sabitlemek (kilitlemek)","e1":"Don't forget to lock the door.","e1t":"Kapıyı kilitlemeyi unutma.","e2":"The lock is broken.","e2t":"Kilit bozuk."},{"w":"lonely","tr":"yalnız","te":"Adjective","tt":"Sıfat","de":"Feeling sad because you are alone","dt":"Yalnız olduğunuz için üzgün hissetme","e1":"He felt lonely in the big city.","e1t":"Büyük şehirde kendini yalnız hissetti.","e2":"It is a lonely road.","e2t":"Bu ıssız (yalnız) bir yol."},{"w":"loose","tr":"gevşek","te":"Adjective","tt":"Sıfat","de":"Not firmly or tightly fixed","dt":"Sıkıca veya sağlamca sabitlenmemiş","e1":"These pants are very loose.","e1t":"Bu pantolon çok gevşek.","e2":"A loose tooth is hurting me.","e2t":"Gevşek bir dişim canımı yakıyor."},{"w":"lost","tr":"kayıp","te":"Adjective","tt":"Sıfat","de":"Not able to find the way","dt":"Yolu bulamama durumu","e1":"We are lost, where is the map?","e1t":"Kaybolduk, harita nerede?","e2":"I lost my wallet yesterday.","e2t":"Dün cüzdanımı kaybettim."},{"w":"lovely","tr":"sevimli / hoş","te":"Adjective","tt":"Sıfat","de":"Very beautiful or pleasant","dt":"Çok güzel veya hoş","e1":"What a lovely surprise!","e1t":"Ne hoş bir sürpriz!","e2":"You have a lovely family.","e2t":"Sevimli/Hoş bir ailen var."},{"w":"luck","tr":"şans","te":"Noun","tt":"İsim","de":"Good things that happen by chance","dt":"Şans eseri olan iyi şeyler","e1":"Good luck in your exam!","e1t":"Sınavında iyi şanslar!","e2":"It was just bad luck.","e2t":"Sadece kötü şanstı."},{"w":"luggage","tr":"bagaj","te":"Noun","tt":"İsim","de":"Bags and suitcases for travel","dt":"Seyahat için çantalar ve valizler","e1":"We have too much luggage.","e1t":"Çok fazla bagajımız var.","e2":"Where can I leave my luggage?","e2t":"Bagajımı nereye bırakabilirim?"},{"w":"lunchbox","tr":"yemek kutusu","te":"Noun","tt":"İsim","de":"A container used to carry food to school or work","dt":"Okula veya işe yemek taşımak için kullanılan kap","e1":"Put your apple in your lunchbox.","e1t":"Elmanı yemek kutuna koy.","e2":"My lunchbox is green.","e2t":"Yemek kutum yeşildir."},{"w":"machine","tr":"makine","te":"Noun","tt":"İsim","de":"A device that uses power to do work","dt":"İş yapmak için güç kullanan cihaz","e1":"The washing machine is broken.","e1t":"Çamaşır makinesi bozuk.","e2":"This machine produces paper.","e2t":"Bu makine kağıt üretiyor."},{"w":"magazine","tr":"dergi","te":"Noun","tt":"İsim","de":"A regular publication with articles and photos","dt":"Makale ve fotoğrafların olduğu düzenli yayın","e1":"I like reading fashion magazines.","e1t":"Moda dergileri okumayı severim.","e2":"The magazine is published monthly.","e2t":"Dergi aylık olarak yayımlanıyor."},{"w":"main","tr":"ana","te":"Adjective","tt":"Sıfat","de":"Most important or largest","dt":"En önemli veya en büyük","e1":"What is the main reason?","e1t":"Ana sebep nedir?","e2":"The main road is closed.","e2t":"Ana yol kapalı."},{"w":"maintain","tr":"sürdürmek","te":"Verb","tt":"Fiil","de":"To keep something in good condition","dt":"Bir şeyi iyi durumda tutmak/devam ettirmek","e1":"It is hard to maintain a large house.","e1t":"Büyük bir evin bakımını yapmak (sürdürmek) zordur.","e2":"You should maintain a healthy diet.","e2t":"Sağlıklı bir diyeti sürdürmelisin."},{"w":"major","tr":"önemli / ana","te":"Adjective","tt":"Sıfat","de":"Very large, important, or serious","dt":"Çok büyük, önemli veya ciddi","e1":"There is a major problem with the engine.","e1t":"Motorda önemli bir sorun var.","e2":"It was a major success.","e2t":"Büyük bir başarıydı."},{"w":"make","tr":"up","te":"makyaj","tt":"Noun","de":"İsim","dt":"Cosmetics applied to the face","e1":"Yüze uygulanan kozmetikler","e1t":"She is wearing too much make","e2":"up.","e2t":"Çok fazla makyaj yapıyor."},{"w":"male","tr":"erkek (cinsiyet)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Belonging to the sex that does not give birth","dt":"Doğum yapmayan cinsiyete ait olan","e1":"The male bird has bright feathers.","e1t":"Erkek kuşun parlak tüyleri vardır.","e2":"Are there more male students in your class?","e2t":"Sınıfında daha fazla erkek öğrenci mi var?"},{"w":"manage","tr":"yönetmek","te":"Verb","tt":"Fiil","de":"To be in charge of or to succeed in doing","dt":"Sorumlu olmak veya yapmayı başarmak","e1":"He manages a small hotel.","e1t":"Küçük bir oteli yönetiyor.","e2":"Did you manage to finish the report?","e2t":"Raporu bitirmeyi başarabildin mi?"},{"w":"manner","tr":"tavır","te":"Noun","tt":"İsim","de":"The way in which something is done or happens","dt":"Bir şeyin yapılma veya olma biçimi","e1":"He has a very polite manner.","e1t":"Çok nazik bir tavrı (tarzı) var.","e2":"It is a common manner in this country.","e2t":"Bu, bu ülkede yaygın bir tutumdur."},{"w":"manual","tr":"el ile yapılan / kitapçık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Done with hands or a book of instructions","dt":"Elle yapılan veya kullanım kılavuzu","e1":"Manual work is very tiring.","e1t":"Fiziksel (el ile yapılan) iş çok yorulucudur.","e2":"Read the user manual first.","e2t":"Önce kullanım kılavuzunu oku."},{"w":"manufacturing","tr":"üretim","te":"Noun","tt":"İsim","de":"Producing goods in large numbers","dt":"Büyük miktarlarda mal üretme","e1":"Manufacturing industry is important for the economy.","e1t":"İmalat sanayii ekonomi için önemlidir.","e2":"They are experts in car manufacturing.","e2t":"Araba üretimi konusunda uzmanlar."},{"w":"mark","tr":"işaret / not","te":"Noun/Verb","tt":"İsim/Fiil","de":"A visible sign or a grade in an exam","dt":"Görünür bir işaret veya sınavdaki bir not","e1":"There is a red mark on your shirt.","e1t":"Gömleğinde kırmızı bir leke (işaret) var.","e2":"I got a good mark in the test.","e2t":"Sınavdan iyi bir not aldım."},{"w":"marriage","tr":"evlilik","te":"Noun","tt":"İsim","de":"The legal relationship between two people","dt":"İki kişi arasındaki yasal ilişki","e1":"They have a happy marriage.","e1t":"Mutlu bir evlilikleri var.","e2":"Marriage is a big responsibility.","e2t":"Evlilik büyük bir sorumluluktur."},{"w":"married","tr":"evli","te":"Adjective","tt":"Sıfat","de":"Having a husband or wife","dt":"Eşi veya kocası olma durumu","e1":"Are you married or single?","e1t":"Evli misiniz yoksa bekar mı?","e2":"They have been married for ten years.","e2t":"On yıldır evliler."},{"w":"marry","tr":"evlenmek","te":"Verb","tt":"Fiil","de":"To become the husband or wife of someone","dt":"Birinin eşi veya kocası olmak","e1":"Will you marry me?","e1t":"Benimle evlenir misin?","e2":"They decided to marry next summer.","e2t":"Gelecek yaz evlenmeye karar verdiler."},{"w":"mass","tr":"kitle / kütle / yığın","te":"Noun/Adjective/Verb","tt":"A large body of matter with no definite shape","de":"Belirli bir şekli olmayan büyük madde yığını","dt":"A mass of people.","e1":"İnsan yığını (kitlesi).","e1t":"Mass production.","e2":"Seri (kitle) üretim.","e2t":""},{"w":"master","tr":"usta","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who is very skilled at something","dt":"Bir konuda çok yetenekli olan kişi","e1":"He is a master of martial arts.","e1t":"O, dövüş sanatlarının ustasıdır.","e2":"It takes years to master a language.","e2t":"Bir dilde uzmanlaşmak (usta olmak) yıllar alır."},{"w":"match","tr":"eş / maç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sports game or things that go well together","dt":"Spor müsabakası veya birbiriyle uyumlu şeyler","e1":"Did you watch the football match?","e1t":"Futbol maçını izledin mi?","e2":"Your tie matches your shirt.","e2t":"Kravatın gömleğinle uyumlu."},{"w":"material","tr":"malzeme","te":"Noun","tt":"İsim","de":"Physical substance used for making things","dt":"Bir şeyler yapmak için kullanılan fiziksel madde","e1":"What material is this table made of?","e1t":"Bu masa hangi malzemeden yapılmış?","e2":"We need more raw materials.","e2t":"Daha fazla ham maddeye ihtiyacımız var."},{"w":"mathematics","tr":"matematik","te":"Noun","tt":"İsim","de":"The study of numbers and shapes","dt":"Sayıların ve şekillerin incelenmesi","e1":"Mathematics is a difficult subject for me.","e1t":"Matematik benim için zor bir ders.","e2":"He is a mathematics professor.","e2t":"O bir matematik profesörüdür."},{"w":"matter","tr":"mesele","te":"Noun/Verb","tt":"İsim/Fiil","de":"A subject or situation or to be important","dt":"Bir konu/durum veya önemli olmak","e1":"It is a private matter.","e1t":"Bu özel bir mesele.","e2":"It doesn't matter.","e2t":"Önemli değil (fark etmez)."},{"w":"maximum","tr":"en yüksek","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The largest amount possible","dt":"Mümkün olan en büyük miktar","e1":"The maximum speed here is 50 km/h.","e1t":"Burada azami (en yüksek) hız saatte 50 km'dir.","e2":"500 people is the maximum.","e2t":"500 kişi üst sınırdır."},{"w":"meaning","tr":"anlam","te":"Noun","tt":"İsim","de":"What a word or symbol represents","dt":"Bir kelime veya sembolün temsil ettiği şey","e1":"What is the meaning of this word?","e1t":"Bu kelimenin anlamı nedir?","e2":"Life has a deep meaning.","e2t":"Hayatın derin bir anlamı var."},{"w":"measure","tr":"ölçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To find the size or amount of something","dt":"Bir şeyin boyutunu veya miktarını bulmak","e1":"Let me measure the room.","e1t":"Odayı ölçeyim.","e2":"We need to take safety measures.","e2t":"Güvenlik önlemleri almamız gerekiyor."},{"w":"media","tr":"medya","te":"Noun","tt":"İsim","de":"TV, radio, and newspapers as a whole","dt":"Bir bütün olarak TV, radyo ve gazeteler","e1":"The media is reporting the news.","e1t":"Medya haberleri rapor ediyor.","e2":"He works in the social media industry.","e2t":"Sosyal medya endüstrisinde çalışıyor."},{"w":"medical","tr":"tıbbi","te":"Adjective","tt":"Sıfat","de":"Relating to the study or practice of medicine","dt":"Tıp eğitimi veya uygulamasıyla ilgili","e1":"He needs medical attention.","e1t":"Tıbbi ilgiye (bakıma) ihtiyacı var.","e2":"I have a medical insurance.","e2t":"Tıbbi sigortam var."},{"w":"medium","tr":"orta","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"In the middle between two sizes or levels","dt":"İki boyut veya seviye arasında ortada olan","e1":"I wear a medium size shirt.","e1t":"Orta beden gömlek giyerim.","e2":"The steak is medium rare.","e2t":"Bonfile orta pişmiş."},{"w":"meet","tr":"buluşmak / tanışmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come together or be introduced","dt":"Bir araya gelmek veya tanıştırılmak","e1":"Let's meet at 2 o'clock.","e1t":"Saat 2'de buluşalım.","e2":"Nice to meet you.","e2t":"Tanıştığımıza memnun oldum."},{"w":"member","tr":"üye","te":"Noun","tt":"İsim","de":"A person belonging to a group or club","dt":"Bir gruba veya kulübe ait olan kişi","e1":"He is a member of the tennis club.","e1t":"Tenis kulübünün bir üyesidir.","e2":"All family members are here.","e2t":"Tüm aile üyeleri burada."},{"w":"memory","tr":"hafıza","te":"Noun","tt":"İsim","de":"The ability to remember or a stored image","dt":"Hatırlama yeteneği veya saklanan görüntü","e1":"He has a very good memory.","e1t":"Çok iyi bir hafızası var.","e2":"I have many happy memories of my childhood.","e2t":"Çocukluğuma dair birçok mutlu anım var."},{"w":"mention","tr":"bahsetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak or write about something briefly","dt":"Bir şey hakkında kısaca konuşmak veya yazmak","e1":"Don't mention it!","e1t":"Lafı bile olmaz (bahsetme)!","e2":"He mentioned your name in the meeting.","e2t":"Toplantıda senin isminden bahsetti."},{"w":"metal","tr":"metal","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard, solid, and shiny substance","dt":"Sert, katı ve parlak madde","e1":"This key is made of metal.","e1t":"Bu anahtar metalden yapılmış.","e2":"Gold and silver are precious metals.","e2t":"Altın ve gümüş değerli metallerdir."},{"w":"method","tr":"yöntem","te":"Noun","tt":"İsim","de":"A particular way of doing something","dt":"Bir şeyi yapmanın belirli bir yolu","e1":"We need a new teaching method.","e1t":"Yeni bir öğretme yöntemine ihtiyacımız var.","e2":"This is the most effective method.","e2t":"Bu en etkili yöntemdir."},{"w":"middle","tr":"orta","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The central point or position","dt":"Merkezi nokta veya konum","e1":"Stand in the middle of the room.","e1t":"Odanın ortasında dur.","e2":"He is in his middle age.","e2t":"Orta yaşlarında."},{"w":"might","tr":"belki","te":"Modal Verb","tt":"Used to express a possibility","de":"Bir olasılığı ifade etmek için kullanılır","dt":"It might rain tonight.","e1":"Bu gece yağmur yağabilir.","e1t":"He might be at home.","e2":"Belki evdedir.","e2t":""},{"w":"mile","tr":"mil","te":"Noun","tt":"İsim","de":"A unit of linear measure equal to 1.6 kilometers","dt":"1.6 kilometreye eşit uzunluk birimi","e1":"It is five miles away.","e1t":"Beş mil uzakta.","e2":"","e2t":""},{"w":"mind","tr":"zihin","te":"Noun/Verb","tt":"İsim/Fiil","de":"The part of a person used for thinking","dt":"Bir insanın düşünmek için kullandığı kısım","e1":"I have a lot on my mind.","e1t":"Zihnimde çok şey var (kafam dolu).","e2":"Do you mind if I sit here?","e2t":"Buraya oturmamın bir sakıncası var mı?"},{"w":"mine","tr":"benimki / maden","te":"Pronoun/Noun","tt":"Belonging to me or a hole for coal/gold","de":"Bana ait olan veya kömür/altın deliği","dt":"This book is mine.","e1":"Bu kitap benimki.","e1t":"He works in a coal mine.","e2":"Kömür madeninde çalışıyor.","e2t":""},{"w":"minimum","tr":"en az","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The smallest amount possible","dt":"Mümkün olan en küçük miktar","e1":"The minimum age for this movie is 18.","e1t":"Bu film için asgari (en az) yaş 18'dir.","e2":"What is the minimum wage?","e2t":"Asgari ücret ne kadar?"},{"w":"minor","tr":"küçük (önem)","te":"Adjective","tt":"Sıfat","de":"Not very large, important, or serious","dt":"Çok büyük, önemli veya ciddi olmayan","e1":"It was only a minor injury.","e1t":"Sadece küçük bir yaralanmaydı.","e2":"There are some minor errors in the report.","e2t":"Raporda bazı küçük hatalar var."},{"w":"mirror","tr":"ayna","te":"Noun","tt":"İsim","de":"A piece of glass that shows you yourself","dt":"Sizi size gösteren cam parçası","e1":"Look in the mirror.","e1t":"Aynaya bak.","e2":"Wall mirror.","e2t":"Duvar aynası."},{"w":"missing","tr":"kayıp","te":"Adjective","tt":"Sıfat","de":"Not found or not present","dt":"Bulunamayan veya mevcut olmayan","e1":"My keys are missing.","e1t":"Anahtarlarım kayıp.","e2":"He is a missing person.","e2t":"O kayıp bir kişi."},{"w":"model","tr":"model","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who wears clothes for photos or a design","dt":"Fotoğraflar için kıyafet giyen kişi veya bir tasarım","e1":"She is a famous fashion model.","e1t":"O ünlü bir moda modelidir.","e2":"This is the latest car model.","e2t":"Bu en son araba modelidir."},{"w":"modern","tr":"modern","te":"Adjective","tt":"Sıfat","de":"Relating to the present or recent times","dt":"Günümüze veya yakın zamanlara ait olan","e1":"I like modern architecture.","e1t":"Modern mimariyi severim.","e2":"This is a very modern kitchen.","e2t":"Bu çok modern bir mutfak."},{"w":"moment","tr":"an","te":"Noun","tt":"İsim","de":"A very brief period of time","dt":"Çok kısa zaman dilimi","e1":"Wait a moment, please.","e1t":"Bir saniye (an) bekleyin lütfen.","e2":"I am busy at the moment.","e2t":"Şu anda meşgulüm."},{"w":"monitor","tr":"ekran","te":"Noun/Verb","tt":"İsim/Fiil","de":"A computer screen or to watch carefully","dt":"Bilgisayar ekranı veya dikkatle izlemek","e1":"The computer monitor is very bright.","e1t":"Bilgisayar monitörü (ekranı) çok parlak.","e2":"Doctors are monitoring his condition.","e2t":"Doktorlar onun durumunu izliyorlar."},{"w":"monkey","tr":"maymun","te":"Noun","tt":"İsim","de":"A type of animal that lives in trees","dt":"Ağaçlarda yaşayan bir hayvan türü","e1":"The monkey is eating a banana.","e1t":"Maymun muz yiyor.","e2":"Monkeys are very clever.","e2t":"Maymunlar çok zekidir."},{"w":"mood","tr":"ruh hali","te":"Noun","tt":"İsim","de":"The way you feel at a particular time","dt":"Belirli bir zamanda hissetme biçimi","e1":"I am in a good mood today.","e1t":"Bugün iyi bir ruh halindeyim.","e2":"Don't talk to him, he is in a bad mood.","e2t":"Onunla konuşma, morali bozuk (kötü ruh halinde)."},{"w":"moral","tr":"ahlaki","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to right and wrong behavior","dt":"Doğru ve yanlış davranışla ilgili","e1":"He is a man of high moral standards.","e1t":"O, yüksek ahlaki standartlara sahip bir adamdır.","e2":"What is the moral of the story?","e2t":"Hikayenin ana fikri (ahlaki dersi) nedir?"},{"w":"mostly","tr":"çoğunlukla","te":"Adverb","tt":"Zarf","de":"Mainly or generally","dt":"Temel olarak veya genellikle","e1":"The students are mostly from Turkey.","e1t":"Öğrenciler çoğunlukla Türkiye'den.","e2":"It is mostly sunny in summer.","e2t":"Yazın çoğunlukla güneşlidir."},{"w":"motor","tr":"motor","te":"Noun","tt":"İsim","de":"A machine that produces motion","dt":"Hareket üreten makine","e1":"The boat has a powerful motor.","e1t":"Teknenin güçlü bir motoru var.","e2":"Turn off the motor.","e2t":"Motoru kapat."},{"w":"movement","tr":"hareket","te":"Noun","tt":"İsim","de":"An act of changing physical position","dt":"Fiziksel konumu değiştirme eylemi","e1":"I saw a movement in the bushes.","e1t":"Çalılıklarda bir hareket gördüm.","e2":"He made a sudden movement.","e2t":"Ani bir hareket yaptı."},{"w":"mud","tr":"çamur","te":"Noun","tt":"İsim","de":"Soft, wet earth","dt":"Yumuşak, ıslak toprak","e1":"Your shoes are covered with mud.","e1t":"Ayakkabıların çamurla kaplanmış.","e2":"Don't play in the mud.","e2t":"Çamurda oynama."},{"w":"museum","tr":"müze","te":"Noun","tt":"İsim","de":"A building where objects are exhibited","dt":"Nesnelerin sergilendiği bina","e1":"The British Museum is in London.","e1t":"British Museum Londra'dadır.","e2":"We spent the whole day in the museum.","e2t":"Tüm günü müzede geçirdik."},{"w":"must","tr":"zorunluluk","te":"Modal Verb","tt":"Used to express necessity","de":"Gerekliliği ifade etmek için kullanılır","dt":"You must wear a seat belt.","e1":"Emniyet kemeri takmak zorundasın.","e1t":"I must go now.","e2":"Şimdi gitmeliyim.","e2t":""},{"w":"mystery","tr":"gizem","te":"Noun","tt":"İsim","de":"Something that is difficult to understand","dt":"Anlaşılması zor olan şey","e1":"His disappearance is a mystery.","e1t":"Onun ortadan kaybolması bir gizemdir.","e2":"I like reading mystery novels.","e2t":"Gizemli romanlar okumayı severim."},{"w":"nail","tr":"çivi / tırnak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A metal pin or the hard part of a finger","dt":"Metal pim veya parmağın sert kısmı","e1":"I need a hammer and some nails.","e1t":"Bir çekice ve birkaç çiviye ihtiyacım var.","e2":"She is painting her nails.","e2t":"Tırnaklarını boyuyor."},{"w":"narrow","tr":"dar","te":"Adjective","tt":"Sıfat","de":"Not wide","dt":"Geniş olmayan","e1":"The street is very narrow.","e1t":"Sokak çok dar.","e2":"He has a narrow mind.","e2t":"Dar bir zihniyeti (görüşü) var."},{"w":"nation","tr":"ulus","te":"Noun","tt":"İsim","de":"A large body of people united by descent","dt":"Soy birliği ile birleşmiş büyük insan topluluğu","e1":"The whole nation is celebrating.","e1t":"Tüm ulus kutlama yapıyor.","e2":"Turkey is a great nation.","e2t":"Türkiye büyük bir ulustur."},{"w":"national","tr":"ulusal","te":"Adjective","tt":"Sıfat","de":"Relating to a whole nation","dt":"Tüm bir ulusla ilgili olan","e1":"Our national flag is red and white.","e1t":"Ulusal bayrağımız kırmızı beyazdır.","e2":"He is a national hero.","e2t":"O bir ulusal kahramandır."},{"w":"natural","tr":"doğal","te":"Adjective","tt":"Sıfat","de":"Existing in or caused by nature","dt":"Doğada var olan veya doğadan kaynaklanan","e1":"I prefer natural food.","e1t":"Doğal yiyecekleri tercih ederim.","e2":"It is a natural disaster.","e2t":"Bu bir doğal felakettir."},{"w":"navigate","tr":"yön bulmak","te":"Verb","tt":"Fiil","de":"To plan and direct the course of a ship/car","dt":"Bir geminin/arabanın rotasını planlamak ve yönetmek","e1":"It's difficult to navigate through the city.","e1t":"Şehir içinde yön bulmak (navigasyon yapmak) zor.","e2":"Use GPS to navigate.","e2t":"Yön bulmak için GPS kullan."},{"w":"neat","tr":"düzenli","te":"Adjective","tt":"Sıfat","de":"Tidy, clean, or organized","dt":"Derli toplu, temiz veya organize","e1":"Your handwriting is very neat.","e1t":"El yazın çok düzenli.","e2":"Keep your room neat and tidy.","e2t":"Odanda düzenli ve temiz tut."},{"w":"negative","tr":"olumsuz","te":"Adjective","tt":"Sıfat","de":"Expressing or containing negation or denial","dt":"Olumsuzlama veya reddetme içeren","e1":"Stop having negative thoughts.","e1t":"Olumsuz düşüncelere sahip olmayı bırak.","e2":"The test result was negative.","e2t":"Test sonucu olumsuz (negatif) çıktı."},{"w":"neighborhood","tr":"mahalle","te":"Noun","tt":"İsim","de":"A district or community within a town or city","dt":"Bir kasaba veya şehir içindeki bölge veya topluluk","e1":"It is a very safe neighborhood.","e1t":"Çok güvenli bir mahalle.","e2":"We grew up in the same neighborhood.","e2t":"Aynı mahallede büyüdük."},{"w":"neither","tr":"hiçbiri","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"Not one nor the other of two people or things","dt":"İki kişi veya şeyden ne biri ne de diğeri","e1":"Neither of my parents is a doctor.","e1t":"Ebeveynlerimin ikisi de doktor değil.","e2":"I like neither tea nor coffee.","e2t":"Ne çayı ne de kahveyi severim."},{"w":"nervous","tr":"gergin","te":"Adjective","tt":"Sıfat","de":"Feeling worried or slightly afraid","dt":"Endişeli veya hafifçe korkmuş hissetme","e1":"I feel nervous before exams.","e1t":"Sınavlardan önce gergin hissederim.","e2":"He has a nervous habit of biting his nails.","e2t":"Tırnaklarını yeme gibi gergin bir alışkanlığı var."},{"w":"nest","tr":"yuva","te":"Noun","tt":"İsim","de":"A structure made by a bird to lay eggs","dt":"Bir kuşun yumurta bırakmak için yaptığı yapı","e1":"I saw a bird's nest in the tree.","e1t":"Ağaçta bir kuş yuvası gördüm.","e2":"The baby birds are in the nest.","e2t":"Yavru kuşlar yuvanın içinde."},{"w":"net","tr":"ağ / file","te":"Noun","tt":"İsim","de":"Material made of string or wire knotted together","dt":"İp veya telden yapılmış gözenekli yapı","e1":"A fishing net.","e1t":"Balık ağı.","e2":"The ball is in the net.","e2t":"Top filelerde (ağda)."},{"w":"network","tr":"ağ","te":"Noun","tt":"İsim","de":"A group or system of interconnected people or things","dt":"Birbirine bağlı insan veya şeylerin grubu veya sistemi","e1":"The social network is growing fast.","e1t":"Sosyal ağ hızla büyüyor.","e2":"We have a strong computer network in the office.","e2t":"Ofiste güçlü bir bilgisayar ağımız var."},{"w":"news","tr":"haber","te":"Noun","tt":"İsim","de":"Newly received or noteworthy information","dt":"Yeni alınan veya kayda değer bilgi","e1":"Have you heard the latest news?","e1t":"Son haberleri duydun mu?","e2":"No news is good news.","e2t":"Haber olmaması iyi haberdir."},{"w":"nice","tr":"hoş / güzel","te":"Adjective","tt":"Sıfat","de":"Pleasant, agreeable, or satisfactory","dt":"Hoş, kabul edilebilir veya tatmin edici","e1":"Have a nice day!","e1t":"İyi günler!","e2":"It's a nice place to visit.","e2t":"Ziyaret etmek için hoş bir yer."},{"w":"niece","tr":"yeğen (kız)","te":"Noun","tt":"İsim","de":"A daughter of one's brother or sister","dt":"Birinin erkek veya kız kardeşinin kızı","e1":"My niece is three years old.","e1t":"Kız yeğenim üç yaşında.","e2":"I bought a gift for my niece.","e2t":"Kız yeğenim için bir hediye aldım."},{"w":"nightmare","tr":"kâbus","te":"Noun","tt":"İsim","de":"A frightening or unpleasant dream","dt":"Korkutucu veya hoş olmayan rüya","e1":"I had a nightmare last night.","e1t":"Dün gece bir kâbus gördüm.","e2":"The traffic was a total nightmare.","e2t":"Trafik tam bir kâbustu."},{"w":"nine","tr":"dokuz","te":"Number","tt":"Sayı","de":"The equivalent of the product of three and three; 9","dt":"3 kere 3'ün karşılığı olan sayı","e1":"I have nine books.","e1t":"Dokuz kitabım var.","e2":"Nine o'clock.","e2t":"Saat dokuz."},{"w":"noise","tr":"gürültü","te":"Noun","tt":"İsim","de":"A sound, especially one that is loud or unpleasant","dt":"Ses, özellikle yüksek veya hoş olmayan","e1":"Don't make too much noise.","e1t":"Çok fazla gürültü yapma.","e2":"I heard a strange noise outside.","e2t":"Dışarıda garip bir ses duydum."},{"w":"none","tr":"hiçbiri","te":"Pronoun","tt":"Zamir","de":"Not any of a group of people or things","dt":"Bir grup insan veya şeyden hiçbiri","e1":"None of the students finished the test.","e1t":"Öğrencilerin hiçbiri testi bitirmedi.","e2":"None of my friends are here.","e2t":"Arkadaşlarımın hiçbiri burada değil."},{"w":"normal","tr":"normal","te":"Adjective","tt":"Sıfat","de":"Usual, typical, or expected","dt":"Olağan, tipik veya beklenen","e1":"It's normal to feel tired after work.","e1t":"İşten sonra yorgun hissetmek normaldir.","e2":"Everything is back to normal.","e2t":"Her şey normale döndü."},{"w":"note","tr":"not","te":"Noun/Verb","tt":"İsim/Fiil","de":"A brief record of facts or thoughts","dt":"Gerçeklerin veya düşüncelerin kısa kaydı","e1":"Write a note for me.","e1t":"Benim için bir not yaz.","e2":"Please note that the shop is closed.","e2t":"Lütfen dükkanın kapalı olduğunu not edin (dikkate alın)."},{"w":"nothing","tr":"hiçbir şey","te":"Pronoun","tt":"Zamir","de":"Not anything; no single thing","dt":"Hiçbir şey; tek bir şey bile değil","e1":"There is nothing in the fridge.","e1t":"Buzdolabında hiçbir şey yok.","e2":"I have nothing to say.","e2t":"Söyleyecek hiçbir şeyim yok."},{"w":"notice","tr":"fark etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become aware of something","dt":"Bir şeyin farkına varmak","e1":"Did you notice her new hair?","e1t":"Onun yeni saçını fark ettin mi?","e2":"There is a notice on the wall.","e2t":"Duvarda bir duyuru (ilan) var."},{"w":"novel","tr":"roman","te":"Noun","tt":"İsim","de":"A long printed story about imaginary characters","dt":"Hayali karakterler hakkındaki uzun basılı hikaye","e1":"I am reading a classic novel.","e1t":"Klasik bir roman okuyorum.","e2":"He wrote his first novel at 20.","e2t":"İlk romanını 20 yaşında yazdı."},{"w":"nowadays","tr":"bugünlerde","te":"Adverb","tt":"Zarf","de":"At the present time, in contrast with the past","dt":"Geçmişin aksine, şu anki zamanda","e1":"Nowadays, everyone uses a smartphone.","e1t":"Bugünlerde herkes akıllı telefon kullanıyor.","e2":"Life is more expensive nowadays.","e2t":"Bugünlerde hayat daha pahalı."},{"w":"nowhere","tr":"hiçbir yer","te":"Adverb","tt":"Zarf","de":"Not in or to any place","dt":"Hiçbir yerde veya hiçbir yere","e1":"There is nowhere to park.","e1t":"Park edecek hiçbir yer yok.","e2":"The cat was nowhere to be found.","e2t":"Kedi hiçbir yerde bulunamadı."},{"w":"object","tr":"nesne","te":"Noun/Verb","tt":"İsim/Fiil","de":"A material thing that can be seen and touched","dt":"Görülebilen ve dokunulabilen maddi şey","e1":"What is that strange object?","e1t":"Şu garip nesne nedir?","e2":"I object to this decision.","e2t":"Bu karara itiraz ediyorum."},{"w":"objective","tr":"amaç","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A goal or something you plan to achieve","dt":"Bir hedef veya başarmayı planladığınız bir şey","e1":"Our main objective is to help people.","e1t":"Ana amacımız insanlara yardım etmek.","e2":"He gave an objective opinion.","e2t":"Tarafsız (nesnel) bir görüş verdi."},{"w":"obligation","tr":"yükümlülük","te":"Noun","tt":"İsim","de":"A duty or commitment","dt":"Bir görev veya taahhüt","e1":"You have an obligation to follow the rules.","e1t":"Kurallara uyma yükümlülüğünüz var.","e2":"It is a legal obligation.","e2t":"Bu yasal bir zorunluluktur."},{"w":"observe","tr":"gözlemlemek","te":"Verb","tt":"Fiil","de":"To watch carefully to learn about something","dt":"Bir şey hakkında bilgi edinmek için dikkatle izlemek","e1":"Scientists observe the stars.","e1t":"Bilim insanları yıldızları gözlemler.","e2":"You must observe the local customs.","e2t":"Yerel geleneklere uymalısın (gözlemlemelisin)."},{"w":"occasion","tr":"özel durum","te":"Noun","tt":"İsim","de":"A particular time or a special event","dt":"Belirli bir zaman veya özel bir etkinlik","e1":"We met on several occasions.","e1t":"Birkaç kez (durumda) karşılaştık.","e2":"A wedding is a special occasion.","e2t":"Düğün özel bir durumdur (etkinliktir)."},{"w":"occupation","tr":"meslek","te":"Noun","tt":"İsim","de":"A job or profession","dt":"Bir iş veya meslek","e1":"Please state your name and occupation.","e1t":"Lütfen adınızı ve mesleğinizi belirtin.","e2":"Teaching is a difficult occupation.","e2t":"Öğretmenlik zor bir meslektir."},{"w":"occur","tr":"meydana gelmek","te":"Verb","tt":"Fiil","de":"To happen or take place","dt":"Gerçekleşmek veya yer almak","e1":"The accident occurred at midnight.","e1t":"Kaza gece yarısı meydana geldi.","e2":"Mistakes can occur anytime.","e2t":"Hatalar her an olabilir."},{"w":"offer","tr":"teklif etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To present something for someone to accept","dt":"Birinin kabul etmesi için bir şey sunmak","e1":"He offered me a job.","e1t":"Bana bir iş teklif etti.","e2":"Thank you for your kind offer.","e2t":"Nazik teklifiniz için teşekkürler."},{"w":"officer","tr":"görevli","te":"Noun","tt":"İsim","de":"A person holding a position of authority","dt":"Yetki sahibi bir pozisyonda olan kişi","e1":"He is a police officer.","e1t":"O bir polis memurudur.","e2":"Talk to the customs officer.","e2t":"Gümrük memuruyla konuşun."},{"w":"official","tr":"resmi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to an authority or public body","dt":"Bir yetkili veya kamu kurumu ile ilgili","e1":"This is an official document.","e1t":"Bu resmi bir belgedir.","e2":"The announcement is official.","e2t":"Duyuru resmidir."},{"w":"oil","tr":"yağ","te":"Noun","tt":"İsim","de":"A thick liquid used for cooking or fuel","dt":"Yemek pişirmek veya yakıt için kullanılan kalın sıvı","e1":"Olive oil is healthy.","e1t":"Zeytinyağı sağlıklıdır.","e2":"Check the engine oil.","e2t":"Motor yağını kontrol et."},{"w":"once","tr":"bir kez","te":"Adverb/Conjunction","tt":"Zarf/Bağlaç","de":"On one occasion or as soon as","dt":"Bir defasında veya olur olmaz","e1":"I have been to London once.","e1t":"Londra'da bir kez bulundum.","e2":"Once you finish, you can leave.","e2t":"Bitirir bitirmez ayrılabilirsin."},{"w":"one","tr":"third","te":"üçte bir","tt":"Number","de":"Sayı","dt":"One of three equal parts","e1":"Üç eşit parçadan biri","e1t":"One","e2":"third of the students are girls.","e2t":"Öğrencilerin üçte biri kız."},{"w":"online","tr":"çevrim içi","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Connected to the internet","dt":"İnternete bağlı olan","e1":"I like shopping online.","e1t":"Çevrim içi alışveriş yapmayı severim.","e2":"The meeting will be online.","e2t":"Toplantı çevrim içi olacak."},{"w":"operate","tr":"işletmek","te":"Verb","tt":"Fiil","de":"To control the functioning of a machine","dt":"Bir makinenin çalışmasını kontrol etmek","e1":"Can you operate this machine?","e1t":"Bu makineyi çalıştırabilir misin?","e2":"The company operates globally.","e2t":"Şirket küresel olarak faaliyet gösteriyor."},{"w":"opinion","tr":"görüş","te":"Noun","tt":"İsim","de":"A view or judgment formed about something","dt":"Bir şey hakkında oluşturulan görüş veya yargı","e1":"What is your opinion on this?","e1t":"Bu konudaki fikrin (görüşün) nedir?","e2":"In my opinion, it is a bad idea.","e2t":"Bence (benim görüşüme göre), bu kötü bir fikir."},{"w":"opportunity","tr":"fırsat","te":"Noun","tt":"İsim","de":"A set of circumstances that makes it possible to do","dt":"Bir şeyi yapmayı mümkün kılan durumlar seti","e1":"Don't miss this opportunity.","e1t":"Bu fırsatı kaçırma.","e2":"I had the opportunity to travel.","e2t":"Seyahat etme fırsatım oldu."},{"w":"opposite","tr":"zıt / karşı","te":"Adjective/Preposition","tt":"Completely different or facing something","de":"Tamamen farklı veya bir şeye bakan","dt":"Black is the opposite of white.","e1":"Siyah, beyazın zıttıdır.","e1t":"The bank is opposite the cafe.","e2":"Banka kafenin karşısındadır.","e2t":""},{"w":"option","tr":"seçenek","te":"Noun","tt":"İsim","de":"A thing that is or may be chosen","dt":"Seçilen veya seçilebilecek olan şey","e1":"We have two options.","e1t":"İki seçeneğimiz var.","e2":"You have no other option.","e2t":"Başka seçeneğin yok."},{"w":"order","tr":"sipariş / düzen","te":"Noun/Verb","tt":"İsim/Fiil","de":"A request for food or the way things are arranged","dt":"Yemek isteği veya şeylerin düzenlenme biçimi","e1":"Are you ready to order?","e1t":"Sipariş vermeye hazır mısınız?","e2":"Keep your room in order.","e2t":"Odanda düzeni koru."},{"w":"ordinary","tr":"sıradan","te":"Adjective","tt":"Sıfat","de":"Normal or not special","dt":"Normal veya özel olmayan","e1":"It was just an ordinary day.","e1t":"Sadece sıradan bir gündü.","e2":"He is an ordinary person.","e2t":"O sıradan biridir."},{"w":"organization","tr":"organizasyon","te":"Noun","tt":"İsim","de":"An organized group of people with a purpose","dt":"Belirli bir amacı olan organize insan grubu","e1":"He works for a world health organization.","e1t":"Bir dünya sağlık örgütü (organizasyonu) için çalışıyor.","e2":"The organization is very successful.","e2t":"Organizasyon çok başarılı."},{"w":"organize","tr":"düzenlemek","te":"Verb","tt":"Fiil","de":"To arrange or plan an event","dt":"Bir etkinliği ayarlamak veya planlamak","e1":"Can you help me organize the party?","e1t":"Partiyi organize etmeme yardım edebilir misin?","e2":"I need to organize my files.","e2t":"Dosyalarımı düzenlemem gerekiyor."},{"w":"origin","tr":"köken","te":"Noun","tt":"İsim","de":"The point or place where something begins","dt":"Bir şeyin başladığı nokta veya yer","e1":"What is the origin of this word?","e1t":"Bu kelimenin kökeni nedir?","e2":"He is of Turkish origin.","e2t":"O Türk kökenlidir."},{"w":"original","tr":"özgün","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Present from the beginning or not a copy","dt":"Başlangıçtan beri mevcut olan veya kopya olmayan","e1":"This is the original document.","e1t":"Bu orijinal (asıl) belgedir.","e2":"He has many original ideas.","e2t":"Birçok özgün fikri var."},{"w":"outdoors","tr":"dışarıda","te":"Adverb/Noun","tt":"In or into the open air","de":"Açık havada veya açık havaya","dt":"Children should play outdoors.","e1":"Çocuklar dışarıda oynamalı.","e1t":"I love the great outdoors.","e2":"Açık havayı (doğayı) seviyorum.","e2t":""},{"w":"overall","tr":"genel olarak","te":"Adverb/Adjective","tt":"Taking everything into account","de":"Her şeyi hesaba katarak","dt":"Overall, the results were good.","e1":"Genel olarak sonuçlar iyiydi.","e1t":"What is the overall cost?","e2":"Genel maliyet nedir?","e2t":""},{"w":"owl","tr":"baykuş","te":"Noun","tt":"İsim","de":"A bird that flies at night","dt":"Gece uçan bir kuş","e1":"The owl has big eyes.","e1t":"Baykuşun büyük gözleri var.","e2":"A white owl.","e2t":"Beyaz bir baykuş."},{"w":"own","tr":"sahip olmak","te":"Adjective/Verb","tt":"Belonging to oneself or to possess","de":"Kendine ait olan veya sahip olmak","dt":"I want to have my own house.","e1":"Kendi evime sahip olmak istiyorum.","e1t":"He owns a large company.","e2":"Büyük bir şirketi var (sahibi).","e2t":""},{"w":"owner","tr":"sahip","te":"Noun","tt":"İsim","de":"A person who owns something","dt":"Bir şeye sahip olan kişi","e1":"Who is the owner of this car?","e1t":"Bu arabanın sahibi kim?","e2":"I am the owner of this shop.","e2t":"Bu dükkanın sahibiyim."},{"w":"pack","tr":"paketlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put things into a bag or a set of things","dt":"Eşyaları bir çantaya koymak veya bir dizi şey","e1":"I need to pack my suitcase.","e1t":"Valizimi hazırlamam (paketlemem) gerekiyor.","e2":"Give me a pack of cigarettes.","e2t":"Bana bir paket sigara ver."},{"w":"package","tr":"paket","te":"Noun","tt":"İsim","de":"An object or group of objects wrapped in paper","dt":"Kağıda sarılmış bir nesne veya nesne grubu","e1":"A package arrived for you today.","e1t":"Bugün sana bir paket geldi.","e2":"What is inside the package?","e2t":"Paketin içinde ne var?"},{"w":"page","tr":"sayfa","te":"Noun","tt":"İsim","de":"One side of a sheet of paper in a book","dt":"Bir kitaptaki kağıdın bir yüzü","e1":"Open your books to page 20.","e1t":"Kitaplarınızı 20. sayfadan açın.","e2":"Read the first page carefully.","e2t":"İlk sayfayı dikkatlice oku."},{"w":"painter","tr":"ressam","te":"Noun","tt":"İsim","de":"An artist who paints pictures","dt":"Resim yapan sanatçı","e1":"Picasso was a famous painter.","e1t":"Picasso ünlü bir ressamdı.","e2":"He works as a house painter.","e2t":"Boyacı (ev boyacısı) olarak çalışıyor."},{"w":"pair","tr":"çift","te":"Noun","tt":"İsim","de":"Two things that are used together","dt":"Birlikte kullanılan iki şey","e1":"I bought a new pair of shoes.","e1t":"Yeni bir çift ayakkabı aldım.","e2":"Where is my other pair of socks?","e2t":"Diğer çift çorabım nerede?"},{"w":"palace","tr":"saray","te":"Noun","tt":"İsim","de":"The official home of a king or queen","dt":"Bir kral veya kraliçenin resmi evi","e1":"Topkapı Palace is in Istanbul.","e1t":"Topkapı Sarayı İstanbul'dadır.","e2":"The palace has many beautiful rooms.","e2t":"Sarayın birçok güzel odası var."},{"w":"pan","tr":"tava","te":"Noun","tt":"İsim","de":"A metal container used for cooking food","dt":"Yemek pişirmek için kullanılan metal kap","e1":"Put the oil in the pan.","e1t":"Yağı tavaya koy.","e2":"Clean the frying pan, please.","e2t":"Kızartma tavasını temizle lütfen."},{"w":"paper","tr":"kağıt","te":"Noun","tt":"İsim","de":"Material used for writing or printing","dt":"Yazmak veya basmak için kullanılan malzeme","e1":"I need a piece of paper.","e1t":"Bir parça kağıda ihtiyacım var.","e2":"The exam paper was difficult.","e2t":"Sınav kağıdı zordu."},{"w":"parallel","tr":"paralel","te":"Adjective","tt":"Sıfat","de":"Side by side and having the same distance","dt":"Yan yana ve aynı mesafede olan","e1":"These two roads are parallel.","e1t":"Bu iki yol birbirine paraleldir.","e2":"Draw two parallel lines.","e2t":"İki paralel çizgi çiz."},{"w":"parrot","tr":"papağan","te":"Noun","tt":"İsim","de":"A colorful bird that can copy voices","dt":"Sesleri taklit edebilen renkli kuş","e1":"My parrot can say \"Hello\".","e1t":"Papağanım \"Merhaba\" diyebiliyor.","e2":"A green parrot.","e2t":"Yeşil bir papağan."},{"w":"part","tr":"parça","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece or section of something larger","dt":"Daha büyük bir şeyin bir parçası veya bölümü","e1":"This is the best part of the movie.","e1t":"Bu filmin en iyi parçası (kısmı).","e2":"We must part ways now.","e2t":"Şimdi yollarımızı ayırmalıyız."},{"w":"participate","tr":"katılmak","te":"Verb","tt":"Fiil","de":"To take part in an action or event","dt":"Bir eylem veya etkinliğe katılmak","e1":"She likes to participate in class.","e1t":"Sınıf içi etkinliklere katılmayı sever.","e2":"Everyone should participate in the meeting.","e2t":"Herkes toplantıya katılmalı."},{"w":"partner","tr":"ortak","te":"Noun","tt":"İsim","de":"A person who takes part in an undertaking","dt":"Bir girişimde yer alan kişi","e1":"He is my business partner.","e1t":"O benim iş ortağım.","e2":"You need to find a dance partner.","e2t":"Bir dans partneri bulman gerekiyor."},{"w":"pass","tr":"geçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move past something or succeed in an exam","dt":"Bir şeyin yanından geçmek veya sınavda başarılı olmak","e1":"I passed the exam with high marks.","e1t":"Sınavı yüksek notlarla geçtim.","e2":"Pass the salt, please.","e2t":"Tuzu uzat (geçir) lütfen."},{"w":"passport","tr":"pasaport","te":"Noun","tt":"İsim","de":"An official document for international travel","dt":"Uluslararası seyahat için resmi belge","e1":"Don't forget your passport.","e1t":"Pasaportunu unutma.","e2":"He showed his passport to the officer.","e2t":"Pasaportunu görevliye gösterdi."},{"w":"past","tr":"geçmiş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The time before the present","dt":"Şimdiki zamandan önceki zaman","e1":"In the past, people traveled by horse.","e1t":"Geçmişte insanlar atla seyahat ederdi.","e2":"It is ten past eight.","e2t":"Saat sekizi on geçiyor."},{"w":"path","tr":"yol","te":"Noun","tt":"İsim","de":"A track or way made for walking","dt":"Yürümek için yapılmış iz veya yol","e1":"Follow the path through the forest.","e1t":"Ormandaki yolu takip et.","e2":"This is the path to success.","e2t":"Bu başarıya giden yoldur."},{"w":"pattern","tr":"model","te":"Noun","tt":"İsim","de":"A repeated decorative design","dt":"Tekrarlanan dekoratif tasarım","e1":"I like the pattern on your shirt.","e1t":"Gömleğindeki deseni (modeli) sevdim.","e2":"There is a clear pattern in the data.","e2t":"Verilerde net bir model var."},{"w":"pause","tr":"duraklamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop for a short time","dt":"Kısa bir süre için durmak","e1":"He paused for a moment to think.","e1t":"Düşünmek için bir an duraksadı.","e2":"Press the pause button.","e2t":"Duraklat (pause) düğmesine bas."},{"w":"payment","tr":"ödeme","te":"Noun","tt":"İsim","de":"The act of paying money","dt":"Para ödeme eylemi","e1":"When is the final payment due?","e1t":"Son ödeme ne zaman yapılacak?","e2":"We accept cash payment only.","e2t":"Sadece nakit ödeme kabul ediyoruz."},{"w":"peace","tr":"barış","te":"Noun","tt":"İsim","de":"A state of quiet or the end of war","dt":"Sessizlik durumu veya savaşın sona ermesi","e1":"We want world peace.","e1t":"Dünya barışı istiyoruz.","e2":"I need some peace and quiet.","e2t":"Biraz huzur (barış) ve sessizliğe ihtiyacım var."},{"w":"peanut","tr":"yer fıstığı","te":"Noun","tt":"İsim","de":"A small nut that grows underground","dt":"Yer altında yetişen küçük kuruyemiş","e1":"Are you allergic to peanuts?","e1t":"Yer fıstığına alerjin var mı?","e2":"I like peanut butter.","e2t":"Yer fıstığı ezmesini severim."},{"w":"pear","tr":"armut","te":"Noun","tt":"İsim","de":"A sweet fruit with a round bottom","dt":"Yuvarlak alt kısmı olan tatlı meyve","e1":"This pear is very juicy.","e1t":"Bu armut çok sulu.","e2":"I bought some apples and pears.","e2t":"Biraz elma ve armut aldım."},{"w":"per","tr":"başına / oranında","te":"Preposition","tt":"Edat","de":"For each; by means of","dt":"Her biri için; aracılığıyla","e1":"The speed limit is 50 km per hour.","e1t":"Hız sınırı saat başına 50 km'dir.","e2":"How much is it per person?","e2t":"Kişi başı ne kadar?"},{"w":"percent","tr":"yüzde","te":"Noun/Adverb","tt":"One part in every hundred","de":"Her yüzdeki bir parça","dt":"Ten percent of the students failed.","e1":"Öğrencilerin yüzde onu başarısız oldu.","e1t":"I agree with you 100 percent.","e2":"Sana yüzde yüz katılıyorum.","e2t":""},{"w":"perfect","tr":"mükemmel","te":"Adjective","tt":"Sıfat","de":"Having no mistakes or being excellent","dt":"Hatasız olma veya mükemmel olma","e1":"Your English is almost perfect.","e1t":"İngilizcen neredeyse mükemmel.","e2":"It was a perfect day.","e2t":"Mükemmel bir gündü."},{"w":"perform","tr":"performans sergilemek","te":"Verb","tt":"Fiil","de":"To carry out a task or act in a show","dt":"Bir görevi yerine getirmek veya gösteride oynamak","e1":"The band will perform live tonight.","e1t":"Grup bu gece canlı performans sergileyecek.","e2":"He performs his job very well.","e2t":"İşini çok iyi yapıyor."},{"w":"performance","tr":"performans","te":"Noun","tt":"İsim","de":"An act of staging a play or concert","dt":"Bir oyunun veya konserin sahnelenme eylemi","e1":"The actor's performance was amazing.","e1t":"Oyuncunun performansı harikaydı.","e2":"We need to improve our performance.","e2t":"Performansımızı geliştirmemiz gerekiyor."},{"w":"period","tr":"dönem","te":"Noun","tt":"İsim","de":"A length of time","dt":"Bir zaman uzunluğu","e1":"This was a difficult period for me.","e1t":"Bu benim için zor bir dönemdi.","e2":"The first period is English class.","e2t":"İlk ders (dönem) İngilizce dersi."},{"w":"permanent","tr":"kalıcı","te":"Adjective","tt":"Sıfat","de":"Lasting or intended to last forever","dt":"Sonsuza kadar süren veya sürmesi amaçlanan","e1":"This is my permanent address.","e1t":"Bu benim kalıcı adresim.","e2":"He found a permanent job.","e2t":"Kalıcı bir iş buldu."},{"w":"permission","tr":"izin","te":"Noun","tt":"İsim","de":"Approval to do something","dt":"Bir şeyi yapmak için onay","e1":"Did you get permission to leave?","e1t":"Ayrılmak için izin aldın mı?","e2":"You need written permission.","e2t":"Yazılı izne ihtiyacın var."},{"w":"personal","tr":"kişisel","te":"Adjective","tt":"Sıfat","de":"Relating to a particular person","dt":"Belirli bir kişiyle ilgili olan","e1":"This is my personal opinion.","e1t":"Bu benim kişisel görüşüm.","e2":"Don't ask personal questions.","e2t":"Kişisel sorular sorma."},{"w":"personality","tr":"kişilik","te":"Noun","tt":"İsim","de":"The qualities that make a person's character","dt":"Bir kişinin karakterini oluşturan nitelikler","e1":"She has a very friendly personality.","e1t":"Çok arkadaş canlısı bir kişiliği var.","e2":"He has a strong personality.","e2t":"Güçlü bir kişiliği var."},{"w":"pet","tr":"evcil hayvan","te":"Noun","tt":"İsim","de":"An animal kept for companionship","dt":"Arkadaşlık için beslenen hayvan","e1":"Do you have any pets?","e1t":"Hiç evcil hayvanın var mı?","e2":"My favorite pet is a dog.","e2t":"En sevdiğim evcil hayvan köpektir."},{"w":"phrase","tr":"ifade","te":"Noun","tt":"İsim","de":"A small group of words","dt":"Küçük bir kelime grubu","e1":"Learn common English phrases.","e1t":"Yaygın İngilizce ifadeleri öğrenin.","e2":"What does this phrase mean?","e2t":"Bu ifade ne anlama geliyor?"},{"w":"physical","tr":"fiziksel","te":"Adjective","tt":"Sıfat","de":"Relating to the body or real objects","dt":"Vücutla veya gerçek nesnelerle ilgili olan","e1":"Physical exercise is healthy.","e1t":"Fiziksel egzersiz sağlıklıdır.","e2":"He has great physical strength.","e2t":"Büyük bir fiziksel gücü var."},{"w":"piano","tr":"piyano","te":"Noun","tt":"İsim","de":"A large musical instrument with keys","dt":"Tuşları olan büyük müzik enstrümanı","e1":"She plays the piano beautifully.","e1t":"Piyanoyu harika çalıyor.","e2":"I want to learn the piano.","e2t":"Piyano öğrenmek istiyorum."},{"w":"pick","tr":"seçmek / toplamak","te":"Verb","tt":"Fiil","de":"To choose or to take from a place","dt":"Seçmek veya bir yerden almak/toplamak","e1":"Pick a card, any card.","e1t":"Bir kart seç, herhangi bir kart.","e2":"We picked fresh flowers.","e2t":"Taze çiçekler topladık."},{"w":"pie","tr":"turta / börek","te":"Noun","tt":"İsim","de":"Fruit or meat baked inside pastry","dt":"Hamur içinde pişmiş meyve veya et","e1":"Apple pie.","e1t":"Elmalı turta.","e2":"Meat pie.","e2t":"Etli börek."},{"w":"piece","tr":"parça","te":"Noun","tt":"İsim","de":"A part of something","dt":"Bir şeyin bir parçası","e1":"Can I have a piece of cake?","e1t":"Bir parça kek alabilir miyim?","e2":"Put the pieces together.","e2t":"Parçaları birleştir."},{"w":"pig","tr":"domuz","te":"Noun","tt":"İsim","de":"A pink farm animal","dt":"Pembe çiftlik hayvanı","e1":"The pig is in the mud.","e1t":"Domuz çamurun içinde.","e2":"A fat pig.","e2t":"Şişman bir domuz."},{"w":"pilot","tr":"pilot","te":"Noun","tt":"İsim","de":"A person who flies an aircraft","dt":"Hava taşıtı uçuran kişi","e1":"He is a commercial airline pilot.","e1t":"O bir ticari havayolu pilotudur.","e2":"The pilot landed the plane safely.","e2t":"Pilot uçağı güvenli bir şekilde indirdi."},{"w":"pipe","tr":"boru","te":"Noun","tt":"İsim","de":"A tube used for carrying water or gas","dt":"Su veya gaz taşımak için kullanılan tüp","e1":"The water pipe is leaking.","e1t":"Su borusu sızdırıyor.","e2":"He is smoking a pipe.","e2t":"Pipo (boru şeklinde) içiyor."},{"w":"place","tr":"yer","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular area or position","dt":"Belirli bir alan veya konum","e1":"This is a beautiful place.","e1t":"Burası güzel bir yer.","e2":"Place the books on the desk.","e2t":"Kitapları masanın üzerine yerleştir."},{"w":"plain","tr":"sade","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Simple or not decorated","dt":"Basit veya süslenmemiş","e1":"I like plain white T","e1t":"shirts.","e2":"Sade beyaz tişörtleri severim.","e2t":"The meaning is quite plain."},{"w":"plastic","tr":"plastik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A light material made from chemicals","dt":"Kimyasallardan yapılan hafif malzeme","e1":"Don't use plastic bags.","e1t":"Plastik torbalar kullanma.","e2":"This toy is made of plastic.","e2t":"Bu oyuncak plastikten yapılmış."},{"w":"platform","tr":"platform","te":"Noun","tt":"İsim","de":"A flat surface for people to stand on","dt":"İnsanların üzerinde durması için düz yüzey","e1":"The train leaves from platform 9.","e1t":"Tren 9. platformdan kalkıyor.","e2":"This is a great online platform.","e2t":"Bu harika bir çevrim içi platform."},{"w":"player","tr":"oyuncu","te":"Noun","tt":"İsim","de":"A person who plays a game or instrument","dt":"Oyun oynayan veya enstrüman çalan kişi","e1":"He is a famous football player.","e1t":"O ünlü bir futbol oyuncusudur.","e2":"We need one more player.","e2t":"Bir oyuncuya daha ihtiyacımız var."},{"w":"pleasant","tr":"hoş","te":"Adjective","tt":"Sıfat","de":"Enjoyable, attractive, or friendly","dt":"Keyifli, çekici veya arkadaşça","e1":"We had a pleasant evening.","e1t":"Hoş bir akşam geçirdik.","e2":"The weather is very pleasant today.","e2t":"Hava bugün çok hoş."},{"w":"pleasure","tr":"zevk","te":"Noun","tt":"İsim","de":"A feeling of happy satisfaction","dt":"Mutlu bir tatmin duygusu","e1":"It is a pleasure to meet you.","e1t":"Sizinle tanışmak bir zevk.","e2":"Reading gives me great pleasure.","e2t":"Okumak bana büyük zevk verir."},{"w":"plenty","tr":"bol miktarda","te":"Pronoun/Noun","tt":"A large or sufficient amount","de":"Büyük veya yeterli miktar","dt":"We have plenty of time.","e1":"Bolca vaktimiz var.","e1t":"There are plenty of jobs available.","e2":"Mevcut birçok (bolca) iş var.","e2t":""},{"w":"pocket","tr":"cep","te":"Noun","tt":"İsim","de":"A small bag sewn into clothing","dt":"Kıyafete dikilmiş küçük çanta/kese","e1":"I have some coins in my pocket.","e1t":"Cebimde biraz madeni para var.","e2":"Put your phone in your pocket.","e2t":"Telefonunu cebine koy."},{"w":"poem","tr":"şiir","te":"Noun","tt":"İsim","de":"A piece of writing with rhythm and feeling","dt":"Ritim ve duygu içeren yazı","e1":"She wrote a beautiful poem.","e1t":"Güzel bir şiir yazdı.","e2":"I like reading English poems.","e2t":"İngilizce şiirler okumayı severim."},{"w":"poet","tr":"şair","te":"Noun","tt":"İsim","de":"A person who writes poems","dt":"Şiir yazan kişi","e1":"Nazım Hikmet is a famous poet.","e1t":"Nazım Hikmet ünlü bir şairdir.","e2":"He wanted to be a poet.","e2t":"Bir şair olmak istiyordu."},{"w":"poetry","tr":"şiir sanatı","te":"Noun","tt":"İsim","de":"Poems in general as a form of literature","dt":"Bir edebiyat türü olarak genel anlamda şiir","e1":"He enjoys reading modern poetry.","e1t":"Modern şiir okumaktan zevk alır.","e2":"She is studying English poetry.","e2t":"İngiliz şiiri üzerine çalışıyor."},{"w":"policy","tr":"politika","te":"Noun","tt":"İsim","de":"A set of ideas or a plan of what to do","dt":"Ne yapılacağına dair fikirler bütünü veya plan","e1":"What is the company's policy on smoking?","e1t":"Şirketin sigara konusundaki politikası nedir?","e2":"We have a strict refund policy.","e2t":"Katı bir iade politikamız var."},{"w":"polish","tr":"parlatmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something smooth and shiny","dt":"Bir şeyi pürüzsüz ve parlak hale getirmek","e1":"I need to polish my shoes.","e1t":"Ayakkabılarımı parlatmam gerekiyor.","e2":"Use a clean cloth for the polish.","e2t":"Parlatma işlemi için temiz bir bez kullan."},{"w":"polite","tr":"kibar","te":"Adjective","tt":"Sıfat","de":"Having or showing good manners","dt":"İyi davranışlara sahip olma veya gösterme","e1":"He is always very polite to everyone.","e1t":"Herkese karşı her zaman çok kibardır.","e2":"It is polite to say thank you.","e2t":"Teşekkür etmek kibarlıktır."},{"w":"political","tr":"politik","te":"Adjective","tt":"Sıfat","de":"Relating to the government or public affairs","dt":"Hükümet veya kamu işleri ile ilgili","e1":"I am not interested in political news.","e1t":"Politik haberlerle ilgilenmiyorum.","e2":"They are fighting for political rights.","e2t":"Politik haklar için savaşıyorlar."},{"w":"politician","tr":"siyasetçi","te":"Noun","tt":"İsim","de":"A person who is professionally involved in politics","dt":"Profesyonel olarak siyasetle uğraşan kişi","e1":"He wants to become a politician.","e1t":"Siyasetçi olmak istiyor.","e2":"The politician gave a long speech.","e2t":"Siyasetçi uzun bir konuşma yaptı."},{"w":"pollution","tr":"kirlilik","te":"Noun","tt":"İsim","de":"Damage caused to water, air, etc., by harmful substances","dt":"Zararlı maddelerin suya, havaya vb. verdiği zarar","e1":"Air pollution is a major problem in cities.","e1t":"Hava kirliliği şehirlerde büyük bir sorundur.","e2":"We must reduce plastic pollution.","e2t":"Plastik kirliliğini azaltmalıyız."},{"w":"pool","tr":"havuz","te":"Noun","tt":"İsim","de":"A small area of still water or a swimming pool","dt":"Küçük bir durgun su alanı veya yüzme havuzu","e1":"The kids are playing in the pool.","e1t":"Çocuklar havuzda oynuyorlar.","e2":"Let's go to the swimming pool.","e2t":"Hadi yüzme havuzuna gidelim."},{"w":"poor","tr":"fakir","te":"Adjective","tt":"Sıfat","de":"Having little money or of low quality","dt":"Az parası olan veya düşük kaliteli","e1":"They help poor families in the village.","e1t":"Köydeki fakir ailelere yardım ediyorlar.","e2":"He has poor eyesight.","e2t":"Onun görme yetisi zayıf (kötü)."},{"w":"popular","tr":"popüler","te":"Adjective","tt":"Sıfat","de":"Liked by many people","dt":"Birçok kişi tarafından sevilen","e1":"This is a very popular song.","e1t":"Bu çok popüler bir şarkı.","e2":"Football is a popular sport in Turkey.","e2t":"Futbol Türkiye'de popüler bir spordur."},{"w":"population","tr":"nüfus","te":"Noun","tt":"İsim","de":"All the people who live in a particular area","dt":"Belirli bir bölgede yaşayan tüm insanlar","e1":"What is the population of Istanbul?","e1t":"İstanbul'un nüfusu nedir?","e2":"The world population is increasing.","e2t":"Dünya nüfusu artıyor."},{"w":"positive","tr":"olumlu","te":"Adjective","tt":"Sıfat","de":"Full of hope and confidence or certain","dt":"Umut ve güven dolu veya emin","e1":"Try to stay positive.","e1t":"Olumlu kalmaya çalış.","e2":"The result was positive.","e2t":"Sonuç olumluydu (pozitifti)."},{"w":"possible","tr":"mümkün","te":"Adjective","tt":"Sıfat","de":"Able to be done or happen","dt":"Yapılması veya olması mümkün olan","e1":"Is it possible to change the date?","e1t":"Tarihi değiştirmek mümkün mü?","e2":"I will come as soon as possible.","e2t":"Mümkün olan en kısa sürede geleceğim."},{"w":"post","tr":"posta","te":"Noun/Verb","tt":"İsim/Fiil","de":"Letters and parcels or to send them","dt":"Mektuplar ve paketler veya onları göndermek","e1":"Did I get any post today?","e1t":"Bugün hiç postam geldi mi?","e2":"I'll post the letter tomorrow.","e2t":"Mektubu yarın postalayacağım."},{"w":"postcard","tr":"kartpostal","te":"Noun","tt":"İsim","de":"A card for sending a message by post","dt":"Posta ile mesaj göndermek için kart","e1":"Send me a postcard from London.","e1t":"Bana Londra'da bir kartpostal gönder.","e2":"I collect old postcards.","e2t":"Eski kartpostalları topluyorum."},{"w":"poster","tr":"poster","te":"Noun","tt":"İsim","de":"A large printed picture used for decoration","dt":"Dekorasyon için kullanılan büyük basılı resim","e1":"He has a poster of a car on his wall.","e1t":"Duvarında bir araba posteri var.","e2":"We put up posters for the event.","e2t":"Etkinlik için posterler astık."},{"w":"potential","tr":"potansiyel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having the capacity to develop into something","dt":"Bir şeye dönüşme kapasitesi olan","e1":"He is a potential buyer.","e1t":"O potansiyel bir alıcıdır.","e2":"She has great potential.","e2t":"Büyük bir potansiyeli var."},{"w":"pound","tr":"pound / vurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A unit of money (UK) or to hit hard","dt":"Para birimi (İngiltere) veya sertçe vurmak","e1":"The book costs ten pounds.","e1t":"Kitap on pound tutuyor.","e2":"He pounded on the door.","e2t":"Kapıya sertçe vurdu."},{"w":"poverty","tr":"yoksulluk","te":"Noun","tt":"İsim","de":"The state of being extremely poor","dt":"Aşırı fakir olma durumu","e1":"Many people live in poverty.","e1t":"Birçok insan yoksulluk içinde yaşıyor.","e2":"We must fight against poverty.","e2t":"Yoksulluğa karşı savaşmalıyız."},{"w":"power","tr":"güç","te":"Noun","tt":"İsim","de":"Ability to do something or control","dt":"Bir şeyi yapma yeteneği veya kontrol","e1":"Knowledge is power.","e1t":"Bilgi güçtür.","e2":"The storm caused a power cut.","e2t":"Fırtına güç (elektrik) kesintisine neden oldu."},{"w":"practical","tr":"pratik","te":"Adjective","tt":"Sıfat","de":"Relating to experience rather than ideas","dt":"Fikirlerden ziyade deneyimle ilgili","e1":"He has a lot of practical experience.","e1t":"Çok fazla pratik deneyimi var.","e2":"It is a practical solution.","e2t":"Pratik bir çözüm."},{"w":"practice","tr":"pratik yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Doing something regularly to improve","dt":"Gelişmek için bir şeyi düzenli yapmak","e1":"I need more practice.","e1t":"Daha fazla pratiğe ihtiyacım var.","e2":"Practice makes perfect.","e2t":"Pratik yapmak mükemmelleştirir."},{"w":"praise","tr":"övmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To express admiration for someone","dt":"Birine hayranlık ifade etmek","e1":"The teacher praised the student.","e1t":"Öğretmen öğrenciyi övdü.","e2":"He deserves praise for his work.","e2t":"Çalışması için övgüyü hak ediyor."},{"w":"pray","tr":"dua etmek","te":"Verb","tt":"Fiil","de":"To speak to God","dt":"Tanrı ile konuşmak","e1":"They pray for peace.","e1t":"Barış için dua ediyorlar.","e2":"I will pray for you.","e2t":"Senin için dua edeceğim."},{"w":"preference","tr":"tercih","te":"Noun","tt":"İsim","de":"A greater liking for one thing over another","dt":"Bir şeyi diğerinden daha çok sevme","e1":"What is your preference?","e1t":"Tercihin nedir?","e2":"I have no preference.","e2t":"Bir tercihim yok (fark etmez)."},{"w":"preparation","tr":"hazırlık","te":"Noun","tt":"İsim","de":"The act of getting ready for something","dt":"Bir şeye hazır olma eylemi","e1":"The preparations for the party are finished.","e1t":"Parti hazırlıkları bitti.","e2":"Preparation is the key to success.","e2t":"Hazırlık başarının anahtarıdır."},{"w":"prepare","tr":"hazırlamak","te":"Verb","tt":"Fiil","de":"To make something ready","dt":"Bir şeyi hazır hale getirmek","e1":"I need to prepare for my exam.","e1t":"Sınavım için hazırlanmam gerekiyor.","e2":"My mother is preparing dinner.","e2t":"Annem akşam yemeğini hazırlıyor."},{"w":"presence","tr":"varlık","te":"Noun","tt":"İsim","de":"The state of being present in a place","dt":"Bir yerde bulunma/var olma durumu","e1":"I felt her presence in the room.","e1t":"Odada onun varlığını hissettim.","e2":"Your presence is required.","e2t":"Varlığınız (orada bulunmanız) gerekiyor."},{"w":"presentation","tr":"sunum","te":"Noun","tt":"İsim","de":"A talk giving information about something","dt":"Bir şey hakkında bilgi veren konuşma","e1":"I have to give a presentation tomorrow.","e1t":"Yarın bir sunum yapmam gerekiyor.","e2":"The presentation was very clear.","e2t":"Sunum çok açıktı."},{"w":"president","tr":"başkan","te":"Noun","tt":"İsim","de":"The leader of a country or organization","dt":"Bir ülkenin veya organizasyonun lideri","e1":"He is the president of the company.","e1t":"O şirketin başkanıdır.","e2":"The president visited the city.","e2t":"Başkan şehri ziyaret etti."},{"w":"press","tr":"basmak / basın","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push something or newspapers and magazines","dt":"Bir şeyi itmek veya gazete ve dergiler","e1":"Press the button to start.","e1t":"Başlatmak için butona bas.","e2":"The freedom of the press is important.","e2t":"Basın özgürlüğü önemlidir."},{"w":"pressure","tr":"baskı","te":"Noun","tt":"İsim","de":"The force produced by pressing or stress","dt":"Basma kuvveti veya stres","e1":"He is under a lot of pressure at work.","e1t":"İş yerinde çok fazla baskı altında.","e2":"Check the tire pressure.","e2t":"Lastik basıncını kontrol et."},{"w":"pretend","tr":"","te":"mış gibi yapmak","tt":"Verb","de":"Fiil","dt":"To behave as if something is true","e1":"Bir şey doğruymuş gibi davranmak","e1t":"Don't pretend to be sick.","e2":"Hastaymış gibi davranma.","e2t":"She pretended not to see me."},{"w":"prevent","tr":"önlemek","te":"Verb","tt":"Fiil","de":"To stop something from happening","dt":"Bir şeyin olmasını durdurmak","e1":"This law will prevent crimes.","e1t":"Bu yasa suçları önleyecektir.","e2":"Wash your hands to prevent illness.","e2t":"Hastalığı önlemek için ellerini yıka."},{"w":"pride","tr":"gurur","te":"Noun","tt":"İsim","de":"A feeling of pleasure in your achievements","dt":"Başarılarınızdan duyduğunuz zevk hissi","e1":"He takes pride in his work.","e1t":"İşiyle gurur duyuyor.","e2":"She felt a sense of pride.","e2t":"Bir gurur duygusu hissetti."},{"w":"priest","tr":"rahip","te":"Noun","tt":"İsim","de":"A person who performs religious ceremonies","dt":"Dini törenleri gerçekleştiren kişi","e1":"The priest is in the church.","e1t":"Rahip kilisededir.","e2":"He became a priest at 25.","e2t":"25 yaşında rahip oldu."},{"w":"primary","tr":"birincil","te":"Adjective","tt":"Sıfat","de":"Main, most important, or first","dt":"Ana, en önemli veya ilk","e1":"My primary goal is to learn English.","e1t":"Birincil hedefim İngilizce öğrenmek.","e2":"She goes to primary school.","e2t":"O ilkokula (birincil okul) gidiyor."},{"w":"principal","tr":"okul müdürü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The head of a school or most important","dt":"Okulun başı veya en önemli","e1":"I have a meeting with the principal.","e1t":"Okul müdürüyle bir toplantım var.","e2":"What is the principal reason for this?","e2t":"Bunun asıl (temel) sebebi nedir?"},{"w":"principle","tr":"ilke","te":"Noun","tt":"İsim","de":"A basic rule or belief","dt":"Temel kural veya inanç","e1":"It is against my principles.","e1t":"Bu benim ilkelerime aykırı.","e2":"We must follow the principles of democracy.","e2t":"Demokrasi ilkelerini takip etmeliyiz."},{"w":"print","tr":"yazdırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce books or marks on paper","dt":"Kitap üretmek veya kağıt üzerinde işaretler (baskı) oluşturmak","e1":"Can you print this document?","e1t":"Bu belgeyi yazdırabilir misin?","e2":"The print is too small to read.","e2t":"Baskı (yazı) okunmayacak kadar küçük."},{"w":"printer","tr":"yazıcı","te":"Noun","tt":"İsim","de":"A machine that prints documents","dt":"Belgeleri yazdıran makine","e1":"I need some ink for the printer.","e1t":"Yazıcı için biraz mürekkebe ihtiyacım var.","e2":"The printer is out of paper.","e2t":"Yazıcıda kağıt bitti."},{"w":"priority","tr":"öncelik","te":"Noun","tt":"İsim","de":"Something that is very important and must be first","dt":"Çok önemli olan ve ilk sırada olması gereken şey","e1":"Health is my top priority.","e1t":"Sağlık benim en büyük önceliğimdir.","e2":"You need to set your priorities.","e2t":"Önceliklerini belirlemelisin."},{"w":"prison","tr":"hapishane","te":"Noun","tt":"İsim","de":"A building where criminals are kept","dt":"Suçluların tutulduğu bina","e1":"He was sent to prison for five years.","e1t":"Beş yıllığına hapishaneye gönderildi.","e2":"Life in prison is difficult.","e2t":"Hapishanede hayat zordur."},{"w":"prisoner","tr":"mahkûm","te":"Noun","tt":"İsim","de":"A person who is kept in prison","dt":"Hapishanede tutulan kişi","e1":"The prisoners were released today.","e1t":"Mahkûmlar bugün serbest bırakıldı.","e2":"He is a political prisoner.","e2t":"O bir siyasi mahkûmdur."},{"w":"private","tr":"özel","te":"Adjective","tt":"Sıfat","de":"Only for one person or group","dt":"Sadece bir kişi veya grup için","e1":"This is a private conversation.","e1t":"Bu özel bir konuşma.","e2":"He goes to a private school.","e2t":"Özel bir okula gidiyor."},{"w":"prize","tr":"ödül","te":"Noun","tt":"İsim","de":"Something given to a winner","dt":"Bir kazanana verilen şey","e1":"He won first prize in the competition.","e1t":"Yarışmada birincilik ödülü kazandı.","e2":"What is the Nobel Prize?","e2t":"Nobel Ödülü nedir?"},{"w":"probably","tr":"muhtemelen","te":"Adverb","tt":"Zarf","de":"Used to say that something is likely","dt":"Bir şeyin olası olduğunu söylemek için kullanılır","e1":"I will probably be late.","e1t":"Muhtemelen geç kalacağım.","e2":"It will probably rain tonight.","e2t":"Muhtemelen bu gece yağmur yağacak."},{"w":"process","tr":"süreç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of actions to achieve a result","dt":"Bir sonuç elde etmek için yapılan eylemler serisi","e1":"Learning a language is a long process.","e1t":"Dil öğrenmek uzun bir süreçtir.","e2":"We are processing your application.","e2t":"Başvurunuzu işleme alıyoruz (süreci yönetiyoruz)."},{"w":"produce","tr":"üretmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make or grow something","dt":"Bir şey yapmak veya yetiştirmek","e1":"This factory produces cars.","e1t":"Bu fabrika araba üretiyor.","e2":"Farmers sell their fresh produce.","e2t":"Çiftçiler taze ürünlerini (mahsullerini) satıyorlar."},{"w":"producer","tr":"yapımcı","te":"Noun","tt":"İsim","de":"A person who manages the money and help for a film","dt":"Bir film için parayı ve yardımı yöneten kişi","e1":"He is a famous Hollywood producer.","e1t":"O ünlü bir Hollywood yapımcısıdır.","e2":"The producer found a new script.","e2t":"Yapımcı yeni bir senaryo buldu."},{"w":"product","tr":"ürün","te":"Noun","tt":"İsim","de":"Something that is made to be sold","dt":"Satılmak üzere yapılan şey","e1":"This is our most popular product.","e1t":"Bu bizim en popüler ürünümüzdür.","e2":"Check the product details online.","e2t":"Ürün detaylarını çevrim içi kontrol edin."},{"w":"production","tr":"üretim","te":"Noun","tt":"İsim","de":"The process of making or growing something","dt":"Bir şeyi yapma veya yetiştirme süreci","e1":"The production of cars has increased.","e1t":"Araba üretimi arttı.","e2":"He works in the production department.","e2t":"Üretim departmanında çalışıyor."},{"w":"profession","tr":"meslek","te":"Noun","tt":"İsim","de":"A job that needs special training or education","dt":"Özel eğitim veya öğretim gerektiren iş","e1":"Teaching is a noble profession.","e1t":"Öğretmenlik asil bir meslektir.","e2":"What is your profession?","e2t":"Mesleğiniz nedir?"},{"w":"professor","tr":"profesör","te":"Noun","tt":"İsim","de":"A teacher of the highest rank in a university","dt":"Üniversitedeki en yüksek rütbeli öğretmen","e1":"He is a professor of history.","e1t":"O bir tarih profesörüdür.","e2":"The professor gave a great lecture.","e2t":"Profesör harika bir ders verdi."},{"w":"profit","tr":"kâr","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money that is earned in trade or business","dt":"Ticaret veya işten kazanılan para","e1":"The company made a huge profit last year.","e1t":"Şirket geçen yıl büyük bir kâr elde etti.","e2":"We need to increase our profit.","e2t":"Kârımızı artırmamız gerekiyor."},{"w":"program","tr":"program","te":"Noun/Verb","tt":"İsim/Fiil","de":"A plan of events or a set of computer instructions","dt":"Etkinlik planı veya bilgisayar komutları seti","e1":"What is your favorite TV program?","e1t":"En sevdiğin TV programı hangisi?","e2":"He learned how to program at school.","e2t":"Okulda program yazmayı (programlamayı) öğrendi."},{"w":"programın için kopyalamaya hazır, a2 seviyesi","tr":"Part 1 (01","te":"50) paketini hazırladım. Formatımız yine aynı: programın veriyi hatasız ayıklayabilmesi için `","tt":"` ayracını ve saf veri yapısını kullanıyoruz.","de":"undefined","dt":"undefined","e1":"undefined","e1t":"","e2":"","e2t":""},{"w":"progress","tr":"ilerleme","te":"Noun/Verb","tt":"İsim/Fiil","de":"Movement to a better or more developed state","dt":"Daha iyi veya gelişmiş bir duruma hareket","e1":"I am making good progress in English.","e1t":"İngilizcede iyi ilerleme kaydediyorum.","e2":"Work is progressing slowly.","e2t":"İş yavaş ilerliyor."},{"w":"promise","tr":"söz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say certainly that you will do something","dt":"Bir şeyi yapacağını kesin olarak söylemek","e1":"I promise to help you.","e1t":"Sana yardım etmeye söz veriyorum.","e2":"Don't break your promise.","e2t":"Sözünü tutmamazlık etme (bozma)."},{"w":"promote","tr":"terfi ettirmek / tanıtmak","te":"Verb","tt":"Fiil","de":"To give a higher rank or to encourage sales","dt":"Daha yüksek bir rütbe vermek veya satışları teşvik etmek","e1":"He was promoted to manager.","e1t":"Müdürlüğe terfi ettirildi.","e2":"They are promoting their new product.","e2t":"Yeni ürünlerini tanıtıyorlar."},{"w":"promotion","tr":"tanıtım / terfi","te":"Noun","tt":"İsim","de":"A move to a higher job or an advertisement","dt":"Daha yüksek bir işe geçiş veya bir reklam","e1":"She got a promotion at work.","e1t":"İş yerinde terfi aldı.","e2":"This is a special sales promotion.","e2t":"Bu özel bir satış tanıtımıdır (promosyonudur)."},{"w":"proof","tr":"kanıt","te":"Noun","tt":"İsim","de":"A fact or piece of information that shows truth","dt":"Gerçeği gösteren bir gerçek veya bilgi parçası","e1":"Do you have proof of your identity?","e1t":"Kimliğinizin kanıtı var mı?","e2":"There is no scientific proof for this.","e2t":"Bunun için bilimsel bir kanıt yok."},{"w":"property","tr":"mülk","te":"Noun","tt":"İsim","de":"Things that someone owns or a building","dt":"Birinin sahip olduğu şeyler veya bir bina","e1":"This bag is my private property.","e1t":"Bu çanta benim özel mülkümdür.","e2":"Property prices are rising in Istanbul.","e2t":"İstanbul'da emlak (mülk) fiyatları yükseliyor."},{"w":"proposal","tr":"teklif","te":"Noun","tt":"İsim","de":"A formal suggestion or plan","dt":"Resmi bir öneri veya plan","e1":"The committee accepted the proposal.","e1t":"Komite teklifi kabul etti.","e2":"He made a marriage proposal.","e2t":"Evlilik teklifi etti."},{"w":"protect","tr":"korumak","te":"Verb","tt":"Fiil","de":"To keep someone or something safe","dt":"Birini veya bir şeyi güvende tutmak","e1":"Wear a hat to protect your head.","e1t":"Başını korumak için bir şapka tak.","e2":"We must protect the environment.","e2t":"Çevreyi korumalıyız."},{"w":"protection","tr":"koruma","te":"Noun","tt":"İsim","de":"The act of keeping something safe","dt":"Bir şeyi güvende tutma eylemi","e1":"This jacket gives protection against rain.","e1t":"Bu ceket yağmura karşı koruma sağlar.","e2":"Data protection is very important.","e2t":"Veri koruması çok önemlidir."},{"w":"prove","tr":"kanıtlamak","te":"Verb","tt":"Fiil","de":"To show that something is true","dt":"Bir şeyin doğru olduğunu göstermek","e1":"Can you prove that you were there?","e1t":"Orada olduğunu kanıtlayabilir misin?","e2":"He proved his skills in the test.","e2t":"Testte becerilerini kanıtladı."},{"w":"provide","tr":"sağlamak","te":"Verb","tt":"Fiil","de":"To give someone something that they need","dt":"Birine ihtiyacı olan bir şeyi vermek","e1":"The hotel provides free breakfast.","e1t":"Otel ücretsiz kahvaltı sağlıyor.","e2":"Can you provide more information?","e2t":"Daha fazla bilgi sağlayabilir misiniz?"},{"w":"public","tr":"halk / kamu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Relating to ordinary people or open to everyone","dt":"Sıradan insanlarla ilgili veya herkese açık","e1":"The library is open to the public.","e1t":"Kütüphane halka açıktır.","e2":"Don't smoke in public places.","e2t":"Halka açık yerlerde sigara içmeyin."},{"w":"publication","tr":"yayın","te":"Noun","tt":"İsim","de":"A book, magazine, or the act of publishing","dt":"Kitap, dergi veya yayımlama eylemi","e1":"This is a weekly publication.","e1t":"Bu haftalık bir yayındır.","e2":"The date of publication is 2024.","e2t":"Yayın tarihi 2024'tür."},{"w":"publish","tr":"yayımlamak","te":"Verb","tt":"Fiil","de":"To prepare and print a book or magazine","dt":"Bir kitabı veya dergiyi hazırlayıp basmak","e1":"The book was published last year.","e1t":"Kitap geçen yıl yayımlandı.","e2":"They publish many educational materials.","e2t":"Birçok eğitim materyali yayımlıyorlar."},{"w":"pull","tr":"çekmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something towards yourself","dt":"Bir şeyi kendine doğru hareket ettirmek","e1":"Pull the door to open it.","e1t":"Açmak için kapıyı çek.","e2":"He pulled the heavy box.","e2t":"Ağır kutuyu çekti."},{"w":"pupil","tr":"öğrenci","te":"Noun","tt":"İsim","de":"A student in school or the center of the eye","dt":"Okuldaki öğrenci veya göz bebeği","e1":"The pupils are listening to the teacher.","e1t":"Öğrenciler öğretmeni dinliyorlar.","e2":"Your pupils get larger in the dark.","e2t":"Göz bebeklerin karanlıkta büyür."},{"w":"purpose","tr":"amaç","te":"Noun","tt":"İsim","de":"The reason why something is done","dt":"Bir şeyin neden yapıldığına dair sebep","e1":"What is the purpose of your visit?","e1t":"Ziyaretinizin amacı nedir?","e2":"He did it on purpose.","e2t":"Onu bilerek (amaçlı olarak) yaptı."},{"w":"push","tr":"itmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something away from yourself","dt":"Bir şeyi kendinden uzağa hareket ettirmek","e1":"Push the button to call the lift.","e1t":"Asansörü çağırmak için butona bas (it).","e2":"He pushed the door open.","e2t":"Kapıyı iterek açtı."},{"w":"put","tr":"koymak","te":"Verb","tt":"Fiil","de":"To move something into a particular position","dt":"Bir şeyi belirli bir konuma getirmek/koymak","e1":"Put the keys on the table.","e1t":"Anahtarları masanın üzerine koy.","e2":"Where did you put my bag?","e2t":"Çantamı nereye koydun?"},{"w":"qualification","tr":"nitelik","te":"Noun","tt":"İsim","de":"A skill or exam that makes you able to do a job","dt":"Bir işi yapabilmenizi sağlayan beceri veya sınav","e1":"What are your professional qualifications?","e1t":"Mesleki nitelikleriniz nelerdir?","e2":"He has a teaching qualification.","e2t":"Onun öğretmenlik belgesi (niteliği) var."},{"w":"quality","tr":"kalite","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"How good or bad something is","dt":"Bir şeyin ne kadar iyi veya kötü olduğu","e1":"We focus on high quality.","e1t":"Yüksek kaliteye odaklanıyoruz.","e2":"This is a quality product.","e2t":"Bu kaliteli bir üründür."},{"w":"quantity","tr":"miktar","te":"Noun","tt":"İsim","de":"An amount or number of something","dt":"Bir şeyin miktarı veya sayısı","e1":"They produce goods in large quantities.","e1t":"Büyük miktarlarda mal üretiyorlar.","e2":"Quality is more important than quantity.","e2t":"Kalite miktardan daha önemlidir."},{"w":"quarter","tr":"çeyrek","te":"Noun","tt":"İsim","de":"One of four equal parts","dt":"Dört eşit parçadan biri","e1":"Cut the cake into quarters.","e1t":"Keki çeyreklere (dört parçaya) böl.","e2":"It's a quarter past seven.","e2t":"Saat yediyi çeyrek geçiyor."},{"w":"queen","tr":"kraliçe","te":"Noun","tt":"İsim","de":"A female ruler of a country","dt":"Bir ülkenin kadın yöneticisi","e1":"The queen lives in the palace.","e1t":"Kraliçe sarayda yaşıyor.","e2":"She was the Queen of England.","e2t":"O, İngiltere kraliçesiydi."},{"w":"quick","tr":"hızlı","te":"Adjective","tt":"Sıfat","de":"Doing something in a short time","dt":"Bir şeyi kısa sürede yapma","e1":"Give me a quick answer.","e1t":"Bana hızlı bir cevap ver.","e2":"He is a quick learner.","e2t":"O hızlı öğrenen biridir."},{"w":"quit","tr":"bırakmak","te":"Verb","tt":"Fiil","de":"To stop doing something or leave a job","dt":"Bir şeyi yapmayı bırakmak veya işten ayrılmak","e1":"He decided to quit smoking.","e1t":"Sigarayı bırakmaya karar verdi.","e2":"She quit her job last week.","e2t":"Geçen hafta işinden ayrıldı."},{"w":"quite","tr":"oldukça","te":"Adverb","tt":"Zarf","de":"To a certain degree; fairly","dt":"Belirli bir dereceye kadar; epey","e1":"The movie was quite good.","e1t":"Film oldukça iyiydi.","e2":"I am quite busy today.","e2t":"Bugün epey meşgulüm."},{"w":"race","tr":"yarış","te":"Noun/Verb","tt":"İsim/Fiil","de":"A competition of speed or a group of people","dt":"Hız yarışması veya bir insan grubu (ırk)","e1":"He won the 100","e1t":"meter race.","e2":"100 metre yarışını kazandı.","e2t":"Human race must protect the earth."},{"w":"raise","tr":"artırmak / yükseltmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To lift something or increase an amount","dt":"Bir şeyi kaldırmak veya bir miktarı artırmak","e1":"Raise your hand if you know the answer.","e1t":"Cevabı biliyorsan elini kaldır.","e2":"The government will raise taxes.","e2t":"Hükümet vergileri artıracak."},{"w":"range","tr":"aralık","te":"Noun","tt":"İsim","de":"A set of different things of the same type","dt":"Aynı türden farklı şeyler seti","e1":"We have a wide range of products.","e1t":"Geniş bir ürün yelpazemiz (aralığımız) var.","e2":"The price range is between $10 and $50.","e2t":"Fiyat aralığı 10 ile 50 dolar arasındadır."},{"w":"rank","tr":"sıra / rütbe","te":"Noun/Verb","tt":"İsim/Fiil","de":"A position in a hierarchy","dt":"Bir hiyerarşideki konum","e1":"He has a high rank in the army.","e1t":"Orduda yüksek bir rütbesi var.","e2":"What is your rank in the competition?","e2t":"Yarışmadaki sıran nedir?"},{"w":"rapid","tr":"hızlı","te":"Adjective","tt":"Sıfat","de":"Fast or happening in a short time","dt":"Hızlı veya kısa sürede olan","e1":"There is a rapid change in technology.","e1t":"Teknolojide hızlı bir değişim var.","e2":"He made a rapid recovery.","e2t":"Hızlı bir iyileşme gösterdi."},{"w":"rare","tr":"nadir","te":"Adjective","tt":"Sıfat","de":"Not common or very frequent","dt":"Yaygın olmayan veya çok sık olmayan","e1":"It is a rare flower.","e1t":"Bu nadir bir çiçektir.","e2":"This is a rare opportunity.","e2t":"Bu nadir bir fırsat."},{"w":"rate","tr":"oran","te":"Noun/Verb","tt":"İsim/Fiil","de":"A measurement of speed or frequency","dt":"Hız veya sıklık ölçümü","e1":"The heart rate is normal.","e1t":"Kalp atış hızı (oranı) normal.","e2":"What is the exchange rate today?","e2t":"Bugün döviz kuru (oranı) nedir?"},{"w":"rather","tr":"daha çok","te":"Adverb","tt":"Zarf","de":"To a slight degree or preferably","dt":"Hafif bir dereceye kadar veya tercihen","e1":"It is rather cold today.","e1t":"Bugün hava oldukça (biraz) soğuk.","e2":"I would rather stay at home.","e2t":"Evde kalmayı tercih ederim (evde kalsam daha iyi)."},{"w":"reach","tr":"ulaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To arrive at a place or be able to touch","dt":"Bir yere varmak veya dokunabilmek","e1":"We reached the hotel at midnight.","e1t":"Gece yarısı otele ulaştık.","e2":"Can you reach the top shelf?","e2t":"Üst rafa ulaşabilir misin?"},{"w":"reaction","tr":"tepki","te":"Noun","tt":"İsim","de":"Something you do or say because of something","dt":"Bir şeyden dolayı yaptığınız veya söylediğiniz şey","e1":"What was his reaction to the news?","e1t":"Habere tepkisi ne oldu?","e2":"It was a natural reaction.","e2t":"Bu doğal bir tepkiydi."},{"w":"reader","tr":"okuyucu","te":"Noun","tt":"İsim","de":"A person who reads","dt":"Okuyan kişi","e1":"She is an avid reader of novels.","e1t":"O hırslı bir roman okuyucusudur.","e2":"The book has millions of readers.","e2t":"Kitabın milyonlarca okuyucusu var."},{"w":"ready","tr":"hazır","te":"Adjective","tt":"Sıfat","de":"Prepared for something","dt":"Bir şey için hazırlanmış","e1":"Are you ready to go?","e1t":"Gitmeye hazır mısın?","e2":"Dinner is ready!","e2t":"Akşam yemeği hazır!"},{"w":"real","tr":"gerçek","te":"Adjective","tt":"Sıfat","de":"Actually existing or true","dt":"Aslında var olan veya doğru","e1":"Is this real gold?","e1t":"Bu gerçek altın mı?","e2":"Tell me the real story.","e2t":"Bana gerçek hikayeyi anlat."},{"w":"reality","tr":"gerçeklik","te":"Noun","tt":"İsim","de":"The state of things as they actually exist","dt":"Şeylerin aslında var olduğu durum","e1":"Virtual reality is very popular.","e1t":"Sanal gerçeklik çok popüler.","e2":"In reality, it is more difficult.","e2t":"Gerçekte, bu daha zor."},{"w":"realize","tr":"fark etmek","te":"Verb","tt":"Fiil","de":"To become aware of something","dt":"Bir şeyin farkına varmak","e1":"I realized that I left my keys at home.","e1t":"Anahtarlarımı evde bıraktığımı fark ettim.","e2":"Did you realize your mistake?","e2t":"Hatabını fark ettin mi?"},{"w":"receive","tr":"almak","te":"Verb","tt":"Fiil","de":"To get or be given something","dt":"Bir şeyi almak veya bir şey verilmek","e1":"I received an email from him.","e1t":"Ondan bir e","e2":"posta aldım.","e2t":"She received a lot of gifts."},{"w":"recent","tr":"son / yakın geçmiş","te":"Adjective","tt":"Sıfat","de":"Having happened or been done only a short time ago","dt":"Çok kısa bir süre önce olmuş veya yapılmış olan","e1":"Have you seen any recent movies?","e1t":"Yakın zamanda çıkmış bir film izledin mi?","e2":"Recent research shows new facts.","e2t":"Son araştırmalar yeni gerçekler gösteriyor."},{"w":"recipe","tr":"tarif","te":"Noun","tt":"İsim","de":"A set of instructions for cooking a dish","dt":"Bir yemek pişirmek için talimatlar seti","e1":"I need a recipe for chocolate cake.","e1t":"Çikolatalı kek için bir tarife ihtiyacım var.","e2":"This is my grandmother's secret recipe.","e2t":"Bu büyükannemin gizli tarifidir."},{"w":"recognize","tr":"tanımak","te":"Verb","tt":"Fiil","de":"To know someone or something because you have seen them before","dt":"Daha önce gördüğünüz için birini veya bir şeyi bilmek","e1":"I didn't recognize him with his new haircut.","e1t":"Yeni saç kesimiyle onu tanıyamadım.","e2":"Do you recognize this song?","e2t":"Bu şarkıyı tanıdın mı?"},{"w":"recommend","tr":"tavsiye etmek","te":"Verb","tt":"Fiil","de":"To suggest that something is good or useful","dt":"Bir şeyin iyi veya yararlı olduğunu önermek","e1":"Can you recommend a good restaurant?","e1t":"İyi bir restoran tavsiye edebilir misin?","e2":"My doctor recommended more exercise.","e2t":"Doktorum daha fazla egzersiz tavsiye etti."},{"w":"record","tr":"kayıt","te":"Noun/Verb","tt":"İsim/Fiil","de":"A written or digital account or to store sound/info","dt":"Yazılı veya dijital bir hesap veya ses/bilgi depolamak","e1":"Keep a record of your expenses.","e1t":"Masraflarının kaydını tut.","e2":"I want to record this song.","e2t":"Bu şarkıyı kaydetmek istiyorum."},{"w":"recover","tr":"iyileşmek","te":"Verb","tt":"Fiil","de":"To become well again after an illness or injury","dt":"Bir hastalık veya yaralanmadan sonra tekrar iyi olmak","e1":"He is recovering from a cold.","e1t":"Nezleden iyileşiyor.","e2":"It took her a long time to recover.","e2t":"İyileşmesi uzun zaman aldı."},{"w":"recycle","tr":"geri dönüştürmek","te":"Verb","tt":"Fiil","de":"To process used materials so they can be used again","dt":"Kullanılmış malzemeleri tekrar kullanılabilmeleri için işlemek","e1":"We should recycle paper and plastic.","e1t":"Kağıt ve plastiği geri dönüştürmeliyiz.","e2":"Recycling is good for the environment.","e2t":"Geri dönüşüm çevre için iyidir."},{"w":"reduce","tr":"azaltmak","te":"Verb","tt":"Fiil","de":"To make something smaller in size, amount, or price","dt":"Bir şeyi boyut, miktar veya fiyat olarak küçültmek","e1":"We need to reduce our plastic waste.","e1t":"Plastik atığımızı azaltmamız gerekiyor.","e2":"The shop reduced the prices.","e2t":"Dükkan fiyatları düşürdü (azalttı)."},{"w":"refer","tr":"atıfta bulunmak","te":"Verb","tt":"Fiil","de":"To mention or talk about something or someone","dt":"Bir şeyden veya birinden bahsetmek veya konuşmak","e1":"Please refer to the manual for more details.","e1t":"Daha fazla detay için kılavuza bakın (atıfta bulunun).","e2":"He referred to his notes during the talk.","e2t":"Konuşma sırasında notlarına atıfta bulundu."},{"w":"reflect","tr":"yansıtmak","te":"Verb","tt":"Fiil","de":"To throw back light or heat or to show something","dt":"Işığı veya ısıyı geri yansıtmak veya bir şeyi göstermek","e1":"The mirror reflects your image.","e1t":"Ayna görüntünü yansıtır.","e2":"The results reflect your hard work.","e2t":"Sonuçlar sıkı çalışmanı yansıtıyor."},{"w":"reform","tr":"reform","te":"Noun/Verb","tt":"İsim/Fiil","de":"An improvement made by changing something","dt":"Bir şeyi değiştirerek yapılan iyileştirme","e1":"The country needs economic reform.","e1t":"Ülkenin ekonomik reforma ihtiyacı var.","e2":"They are trying to reform the education system.","e2t":"Eğitim sisteminde reform yapmaya çalışıyorlar."},{"w":"refuse","tr":"reddetmek","te":"Verb","tt":"Fiil","de":"To say that you will not do or accept something","dt":"Bir şeyi yapmayacağınızı veya kabul etmeyeceğinizi söylemek","e1":"He refused to answer the question.","e1t":"Soruyu cevaplamayı reddetti.","e2":"She refused his invitation.","e2t":"Onun davetini reddetti."},{"w":"region","tr":"bölge","te":"Noun","tt":"İsim","de":"A particular area of a country or the world","dt":"Bir ülkenin veya dünyanın belirli bir alanı","e1":"Which region of Turkey are you from?","e1t":"Türkiye'nin hangi bölgesindensin?","e2":"This region is famous for its grapes.","e2t":"Bu bölge üzümleriyle ünlüdür."},{"w":"regret","tr":"pişman olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel sad or sorry about something in the past","dt":"Geçmişteki bir şey için üzgün veya pişman hissetmek","e1":"I regret saying those words.","e1t":"O sözleri söylediğim için pişmanım.","e2":"My only regret is not traveling more.","e2t":"Tek pişmanlığım daha fazla seyahat etmemek."},{"w":"regular","tr":"düzenli","te":"Adjective","tt":"Sıfat","de":"Happening or done often or at fixed intervals","dt":"Sık sık veya sabit aralıklarla olan veya yapılan","e1":"He is a regular customer here.","e1t":"O buranın düzenli bir müşterisidir.","e2":"You should do regular exercise.","e2t":"Düzenli egzersiz yapmalısın."},{"w":"regulation","tr":"düzenleme","te":"Noun","tt":"İsim","de":"An official rule or the act of controlling","dt":"Resmi bir kural veya kontrol etme eylemi","e1":"New safety regulations were introduced.","e1t":"Yeni güvenlik düzenlemeleri getirildi.","e2":"We must follow the government regulations.","e2t":"Hükümet düzenlemelerine uymalıyız."},{"w":"relation","tr":"ilişki","te":"Noun","tt":"İsim","de":"A connection between two or more things","dt":"İki veya daha fazla şey arasındaki bağlantı","e1":"Is there a relation between these events?","e1t":"Bu olaylar arasında bir ilişki var mı?","e2":"He is a distant relation of mine.","e2t":"O benim uzak bir akrabamdır (ilişkimdir)."},{"w":"relationship","tr":"ilişki","te":"Noun","tt":"İsim","de":"The way in which two people or groups behave","dt":"İki kişi veya grubun birbirine karşı davranış biçimi","e1":"They have a very good relationship.","e1t":"Çok iyi bir ilişkileri var.","e2":"Building a relationship takes time.","e2t":"Bir ilişki kurmak zaman alır."},{"w":"relative","tr":"akraba","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person connected by blood or marriage","dt":"Kan veya evlilik bağıyla bağlı olan kişi","e1":"All my relatives live in this city.","e1t":"Tüm akrabalarım bu şehirde yaşıyor.","e2":"The price is relative to the quality.","e2t":"Fiyat kaliteye göre görelidir (bağlantılıdır)."},{"w":"relax","tr":"rahatlamak","te":"Verb","tt":"Fiil","de":"To rest or become less tense","dt":"Dinlenmek veya daha az gergin olmak","e1":"I like to relax with a book.","e1t":"Bir kitapla rahatlamayı severim.","e2":"Relax, everything will be fine.","e2t":"Rahatla, her şey iyi olacak."},{"w":"release","tr":"serbest bırakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To allow to go free or make something available","dt":"Serbest kalmasına izin vermek veya bir şeyi mevcut kılmak","e1":"They released the prisoner.","e1t":"Mahkûmu serbest bıraktılar.","e2":"The new album will be released tomorrow.","e2t":"Yeni albüm yarın yayınlanacak (piyasaya sürülecek)."},{"w":"relevant","tr":"ilgili","te":"Adjective","tt":"Sıfat","de":"Closely connected to the matter at hand","dt":"Eldeki meseleyle yakından bağlantılı olan","e1":"Please provide all relevant documents.","e1t":"Lütfen tüm ilgili belgeleri sağlayın.","e2":"This information is not relevant to our case.","e2t":"Bu bilgi bizim durumumuzla ilgili değil."},{"w":"relief","tr":"rahatlama","te":"Noun","tt":"İsim","de":"A feeling of reassurance and relaxation","dt":"Güven ve rahatlama hissi","e1":"It was a relief to hear the news.","e1t":"Haberi duymak bir rahatlamaydı.","e2":"The medicine gave me quick relief.","e2t":"İlaç bana hızlı bir rahatlama sağladı."},{"w":"religion","tr":"din","te":"Noun","tt":"İsim","de":"The belief in and worship of a god or gods","dt":"Bir tanrıya veya tanrılara olan inanç ve tapınma","e1":"What is your religion?","e1t":"Dininiz nedir?","e2":"Freedom of religion is important.","e2t":"Din özgürlüğü önemlidir."},{"w":"remain","tr":"kalmak","te":"Verb","tt":"Fiil","de":"To stay in the same place or condition","dt":"Aynı yerde veya durumda kalmak","e1":"Please remain in your seats.","e1t":"Lütfen koltuklarınızda kalın.","e2":"The problem remains unsolved.","e2t":"Sorun çözülmeden kalıyor."},{"w":"remark","tr":"yorum","te":"Noun/Verb","tt":"İsim/Fiil","de":"A brief statement of an opinion","dt":"Bir görüşün kısa ifadesi","e1":"He made a strange remark.","e1t":"Garip bir yorum yaptı.","e2":"She remarked on the beautiful view.","e2t":"Güzel manzara hakkında yorumda bulundu."},{"w":"remind","tr":"hatırlatmak","te":"Verb","tt":"Fiil","de":"To cause someone to remember something","dt":"Birinin bir şeyi hatırlamasını sağlamak","e1":"Please remind me to call my mother.","e1t":"Lütfen annemi aramamı hatırlat.","e2":"This song reminds me of my childhood.","e2t":"Bu şarkı bana çocukluğumu hatırlatıyor."},{"w":"remote","tr":"uzaktan","te":"Adjective","tt":"Sıfat","de":"Far away in space or time","dt":"Mekan veya zaman olarak uzak","e1":"We live in a remote village.","e1t":"Uzak bir köyde yaşıyoruz.","e2":"Where is the TV remote control?","e2t":"TV uzaktan kumandası nerede?"},{"w":"remove","tr":"çıkarmak","te":"Verb","tt":"Fiil","de":"To take something away from a place","dt":"Bir şeyi bir yerden uzaklaştırmak/almak","e1":"Please remove your shoes.","e1t":"Lütfen ayakkabılarınızı çıkarın.","e2":"He removed the old paint from the wall.","e2t":"Duvardaki eski boyayı çıkardı."},{"w":"repair","tr":"tamir etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fix something that is damaged or broken","dt":"Hasarlı veya bozuk bir şeyi onarmak","e1":"Can you repair my watch?","e1t":"Saatimi tamir edebilir misin?","e2":"The car is under repair.","e2t":"Araba tamirde."},{"w":"repeat","tr":"tekrar etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say or do something again","dt":"Bir şeyi tekrar söylemek veya yapmak","e1":"Can you repeat that, please?","e1t":"Lütfen onu tekrar edebilir misiniz?","e2":"Don't repeat your mistakes.","e2t":"Hatalarını tekrar etme."},{"w":"replace","tr":"değiştirmek / yerine koymak","te":"Verb","tt":"Fiil","de":"To take the place of or provide a substitute","dt":"Yerine geçmek veya bir yedek sağlamak","e1":"I need to replace my old computer.","e1t":"Eski bilgisayarımı değiştirmem gerekiyor.","e2":"We replaced the broken window.","e2t":"Kırık pencereyi değiştirdik."},{"w":"reply","tr":"cevap vermek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say or write something as an answer","dt":"Yanıt olarak bir şey söylemek veya yazmak","e1":"Please reply to my email soon.","e1t":"Lütfen e","e2":"postama yakında cevap verin.","e2t":"I am waiting for his reply."},{"w":"report","tr":"rapor","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal account or to give information","dt":"Resmi bir hesap veya bilgi vermek","e1":"I have to finish the annual report.","e1t":"Yıllık raporu bitirmem gerekiyor.","e2":"The witness reported the accident.","e2t":"Tanık kazayı bildirdi (rapor etti)."},{"w":"reporter","tr":"muhabir","te":"Noun","tt":"İsim","de":"A person who reports news for TV or newspapers","dt":"TV veya gazeteler için haber yapan kişi","e1":"She is a news reporter.","e1t":"O bir haber muhabiridir.","e2":"The reporter asked many questions.","e2t":"Muhabir birçok soru sordu."},{"w":"represent","tr":"temsil etmek","te":"Verb","tt":"Fiil","de":"To act or speak on behalf of someone or a group","dt":"Biri veya bir grup adına hareket etmek veya konuşmak","e1":"He represents our company in Turkey.","e1t":"Şirketimizi Türkiye'de temsil ediyor.","e2":"What does this symbol represent?","e2t":"Bu sembol neyi temsil ediyor?"},{"w":"request","tr":"talep","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act of asking politely for something","dt":"Bir şeyi nazikçe isteme eylemi","e1":"Thank you for your request.","e1t":"Talebiniz için teşekkürler.","e2":"He requested a meeting with the manager.","e2t":"Müdürle bir toplantı talep etti."},{"w":"require","tr":"gerektirmek","te":"Verb","tt":"Fiil","de":"To need something for a particular purpose","dt":"Belirli bir amaç için bir şeye ihtiyaç duymak","e1":"This job requires a lot of travel.","e1t":"Bu iş çok fazla seyahat gerektiriyor.","e2":"We require a written application.","e2t":"Yazılı bir başvuru gerektiriyoruz."},{"w":"research","tr":"araştırma","te":"Noun/Verb","tt":"İsim/Fiil","de":"The systematic study of materials and sources","dt":"Materyallerin ve kaynakların sistematik çalışması","e1":"He is doing research on cancer.","e1t":"Kanser üzerine araştırma yapıyor.","e2":"I need to research this topic.","e2t":"Bu konuyu araştırmam gerekiyor."},{"w":"researcher","tr":"araştırmacı","te":"Noun","tt":"İsim","de":"A person who carries out academic research","dt":"Akademik araştırma yürüten kişi","e1":"She is a scientific researcher.","e1t":"O bir bilimsel araştırmacıdır.","e2":"Many researchers are working on this.","e2t":"Birçok araştırmacı bunun üzerinde çalışıyor."},{"w":"reservation","tr":"rezervasyon","te":"Noun","tt":"İsim","de":"An arrangement to have something kept for you","dt":"Bir şeyin sizin için tutulması için yapılan düzenleme","e1":"I have a reservation for two people.","e1t":"İki kişilik bir rezervasyonum var.","e2":"Can I make a table reservation?","e2t":"Masa rezervasyonu yapabilir miyim?"},{"w":"resident","tr":"ikamet eden","te":"Noun","tt":"İsim","de":"A person who lives in a particular place","dt":"Belirli bir yerde yaşayan kişi","e1":"He is a resident of Istanbul.","e1t":"O bir İstanbul sakinidir (ikamet edenidir).","e2":"The local residents are happy.","e2t":"Yerel sakinler mutlu."},{"w":"resist","tr":"direnmek","te":"Verb","tt":"Fiil","de":"To fight against or refuse to accept","dt":"Karşı savaşmak veya kabul etmeyi reddetmek","e1":"It is hard to resist chocolate.","e1t":"Çikolataya direnmek zordur.","e2":"He resisted the new rules.","e2t":"Yeni kurallara direndi."},{"w":"resistance","tr":"direnç","te":"Noun","tt":"İsim","de":"The refusal to accept or comply with something","dt":"Bir şeyi kabul etmeyi veya ona uymayı reddetme","e1":"There was a lot of resistance to the plan.","e1t":"Plana karşı çok fazla direnç vardı.","e2":"He has a high resistance to illness.","e2t":"Hastalığa karşı yüksek bir direnci var."},{"w":"resolve","tr":"çözmek","te":"Verb","tt":"Fiil","de":"To find a solution to a problem or argument","dt":"Bir soruna veya tartışmaya çözüm bulmak","e1":"We must resolve this issue quickly.","e1t":"Bu meseleyi hızlıca çözmeliyiz.","e2":"They resolved their differences.","e2t":"Farklılıklarını (anlaşmazlıklarını) çözdüler."},{"w":"respect","tr":"saygı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of admiration for someone","dt":"Birine duyulan hayranlık/saygı hissi","e1":"You must show respect to your elders.","e1t":"Büyüklerinize saygı göstermelisiniz.","e2":"I respect your opinion.","e2t":"Görüşüne saygı duyuyorum."},{"w":"respond","tr":"yanıt vermek","te":"Verb","tt":"Fiil","de":"To say or do something as a reaction","dt":"Tepki olarak bir şey söylemek veya yapmak","e1":"He didn't respond to my email.","e1t":"E","e2":"postama yanıt vermedi.","e2t":"You must respond quickly in an emergency."},{"w":"response","tr":"yanıt","te":"Noun","tt":"İsim","de":"An answer or reaction","dt":"Bir cevap veya tepki","e1":"Thank you for your quick response.","e1t":"Hızlı yanıtınız için teşekkürler.","e2":"I am waiting for their response.","e2t":"Onların yanıtını bekliyorum."},{"w":"responsibility","tr":"sorumluluk","te":"Noun","tt":"İsim","de":"The state of having a duty to deal with something","dt":"Bir şeyle ilgilenme görevi olma durumu","e1":"It is your responsibility to finish the task.","e1t":"Görevi bitirmek senin sorumluluğundadır.","e2":"He has a lot of responsibility at work.","e2t":"İş yerinde çok fazla sorumluluğu var."},{"w":"rest","tr":"dinlenmek / geri kalan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To relax or the part that remains","dt":"Dinlenmek veya geri kalan kısım","e1":"You look tired, you should rest.","e1t":"Yorgun görünüyorsun, dinlenmelisin.","e2":"I will do the rest of the work tomorrow.","e2t":"İşin geri kalanını yarın yapacağım."},{"w":"retire","tr":"emekli olmak","te":"Verb","tt":"Fiil","de":"To stop working because of old age","dt":"Yaşlılık nedeniyle çalışmayı bırakmak","e1":"My father retired last year.","e1t":"Babam geçen yıl emekli oldu.","e2":"She plans to retire at sixty.","e2t":"Altmış yaşında emekli olmayı planlıyor."},{"w":"return","tr":"geri dönmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come or go back to a place","dt":"Bir yere geri gelmek veya gitmek","e1":"I will return home at 6 PM.","e1t":"Akşam 6'da eve döneceğim.","e2":"We are waiting for his return.","e2t":"Onun dönüşünü bekliyoruz."},{"w":"reveal","tr":"ortaya çıkarmak","te":"Verb","tt":"Fiil","de":"To make something known that was secret","dt":"Gizli olan bir şeyi bilinir hale getirmek","e1":"The report revealed the truth.","e1t":"Rapor gerçeği ortaya çıkardı.","e2":"She revealed her secret to me.","e2t":"Sırrını bana açtı (ortaya çıkardı)."},{"w":"review","tr":"gözden geçirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To examine something again or a report","dt":"Bir şeyi tekrar incelemek veya bir rapor/eleştiri","e1":"We need to review the plan.","e1t":"Planı gözden geçirmemiz gerekiyor.","e2":"I read a review of the new movie.","e2t":"Yeni filmin bir eleştirisini okudum."},{"w":"rich","tr":"zengin","te":"Adjective","tt":"Sıfat","de":"Having a lot of money or resources","dt":"Çok parası veya kaynağı olan","e1":"He is a very rich businessman.","e1t":"O çok zengin bir iş adamıdır.","e2":"Turkey is rich in history.","e2t":"Türkiye tarih açısından zengindir."},{"w":"ride","tr":"binmek / sürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To sit on and control a horse or bike","dt":"Bir ata veya bisiklete binip onu kontrol etmek","e1":"Can you ride a bike?","e1t":"Bisiklet sürebiliyor musun?","e2":"It was a long bus ride.","e2t":"Uzun bir otobüs yolculuğuydu."},{"w":"rise","tr":"yükselmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move upwards or an increase","dt":"Yukarı doğru hareket etmek veya bir artış","e1":"The sun rises in the east.","e1t":"Güneş doğudan doğar.","e2":"There is a rise in prices.","e2t":"Fiyatlarda bir artış var."},{"w":"risk","tr":"risk","te":"Noun/Verb","tt":"İsim/Fiil","de":"The possibility of something bad happening","dt":"Kötü bir şey olma olasılığı","e1":"Is it worth the risk?","e1t":"Bu riske değer mi?","e2":"Don't risk your health.","e2t":"Sağlığını riske atma."},{"w":"rock","tr":"kaya","te":"Noun","tt":"İsim","de":"A large piece of stone","dt":"Büyük taş parçası","e1":"The boat hit a rock.","e1t":"Tekne bir kayaya çarptı.","e2":"He likes rock music.","e2t":"Rock müziği sever."},{"w":"role","tr":"rol","te":"Noun","tt":"İsim","de":"An actor's part or a person's function","dt":"Bir oyuncunun parçası veya bir kişinin işlevi","e1":"She played the leading role in the film.","e1t":"Filmde başrolü oynadı.","e2":"What is your role in this project?","e2t":"Bu projedeki rolün nedir?"},{"w":"roll","tr":"yuvarlanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move by turning over and over","dt":"Döne döne hareket etmek","e1":"The ball rolled down the hill.","e1t":"Top tepeden aşağı yuvarlandı.","e2":"I'll have a cinnamon roll.","e2t":"Bir tarçınlı çörek (rulo) alacağım."},{"w":"root","tr":"kök","te":"Noun","tt":"İsim","de":"The part of a plant that grows underground","dt":"Bir bitkinin yer altında büyüyen kısmı","e1":"The tree has deep roots.","e1t":"Ağacın derin kökleri var.","e2":"Money is the root of all evil.","e2t":"Para tüm kötülüklerin köküdür."},{"w":"rope","tr":"halat","te":"Noun","tt":"İsim","de":"Strong thick cord made by twisting","dt":"Bükülerek yapılan güçlü kalın kordon","e1":"He tied the boat with a rope.","e1t":"Tekneyi bir halatla bağladı.","e2":"We need a long rope.","e2t":"Uzun bir halata ihtiyacımız var."},{"w":"rough","tr":"kaba / pürüzlü","te":"Adjective","tt":"Sıfat","de":"Not smooth or gentle","dt":"Pürüzsüz veya nazik olmayan","e1":"The sea is very rough today.","e1t":"Bugün deniz çok dalgalı (sert).","e2":"He had a rough childhood.","e2t":"Zorlu (kaba) bir çocukluk geçirdi."},{"w":"round","tr":"yuvarlak","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Shaped like a circle or ball","dt":"Daire veya top şeklinde olan","e1":"The earth is round.","e1t":"Dünya yuvarlaktır.","e2":"We sat at a round table.","e2t":"Yuvarlak bir masada oturduk."},{"w":"routine","tr":"rutin","te":"Noun","tt":"İsim","de":"A usual way of doing things","dt":"Bir şeyleri yapmanın olağan yolu","e1":"I need a daily routine.","e1t":"Günlük bir rutine ihtiyacım var.","e2":"Exercise is part of my routine.","e2t":"Egzersiz rutinim bir parçasıdır."},{"w":"row","tr":"sıra","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of things or to move a boat with oars","dt":"Şeylerin bir çizgisi veya bir tekneyi kürekle hareket ettirmek","e1":"We sat in the front row.","e1t":"Ön sırada oturduk.","e2":"He is rowing the boat.","e2t":"Tekneyi kürekle sürüyor."},{"w":"royal","tr":"kraliyet","te":"Adjective","tt":"Sıfat","de":"Relating to a king or queen","dt":"Bir kral veya kraliçe ile ilgili","e1":"The royal family lives here.","e1t":"Kraliyet ailesi burada yaşıyor.","e2":"It was a royal wedding.","e2t":"Bir kraliyet düğünüydü."},{"w":"rub","tr":"ovmak","te":"Verb","tt":"Fiil","de":"To move your hand back and forth over a surface","dt":"Elinizi bir yüzey üzerinde ileri geri hareket ettirmek","e1":"Rub your hands to get warm.","e1t":"Isınmak için ellerini ov.","e2":"He rubbed his tired eyes.","e2t":"Yorgun gözlerini ovuşturdu."},{"w":"rubbish","tr":"çöp","te":"Noun","tt":"İsim","de":"Waste material; garbage","dt":"Atık malzeme; çöp","e1":"Throw the rubbish in the bin.","e1t":"Çöpü kutuya at.","e2":"That's absolute rubbish!","e2t":"Bu tamamen saçmalık (çöp)!"},{"w":"rude","tr":"kaba","te":"Adjective","tt":"Sıfat","de":"Not polite; offensive","dt":"Nazik olmayan; saldırgan","e1":"Don't be rude to your teacher.","e1t":"Öğretmenine karşı kaba olma.","e2":"It was a rude remark.","e2t":"Kaba bir yorumdu."},{"w":"rule","tr":"kural","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official instruction or to control","dt":"Resmi bir talimat veya kontrol etmek","e1":"You must follow the rules.","e1t":"Kurallara uymak zorundasın.","e2":"The king ruled for forty years.","e2t":"Kral kırk yıl boyunca hüküm sürdü (yönetti)."},{"w":"runner","tr":"koşucu","te":"Noun","tt":"İsim","de":"A person who runs","dt":"Koşan kişi","e1":"He is a fast runner.","e1t":"O hızlı bir koşucudur.","e2":"There were 500 runners in the race.","e2t":"Yarışta 500 koşucu vardı."},{"w":"rural","tr":"kırsal","te":"Adjective","tt":"Sıfat","de":"Relating to the countryside","dt":"Kırsal alanla ilgili olan","e1":"We live in a rural area.","e1t":"Kırsal bir bölgede yaşıyoruz.","e2":"I prefer rural life to city life.","e2t":"Kırsal hayatı şehir hayatına tercih ederim."},{"w":"safety","tr":"güvenlik","te":"Noun","tt":"İsim","de":"The state of being safe from danger","dt":"Tehlikeden uzak olma durumu","e1":"Safety is our top priority.","e1t":"Güvenlik en büyük önceliğimizdir.","e2":"Keep your documents in safety.","e2t":"Belgelerini güvende tut."},{"w":"sail","tr":"yelken açmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To travel on water in a boat","dt":"Bir teknede su üzerinde seyahat etmek","e1":"I want to learn how to sail.","e1t":"Yelken açmayı (tekne kullanmayı) öğrenmek istiyorum.","e2":"The ship has white sails.","e2t":"Geminin beyaz yelkenleri var."},{"w":"sale","tr":"satış","te":"Noun","tt":"İsim","de":"The act of selling or a period of lower prices","dt":"Satma eylemi veya düşük fiyat dönemi","e1":"The house is for sale.","e1t":"Ev satılık.","e2":"I bought this shirt in the sale.","e2t":"Bu gömleği indirimden (satıştan) aldım."},{"w":"sample","tr":"örnek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small part used to show what the whole is like","dt":"Bütünün nasıl olduğunu gösteren küçük bir parça","e1":"Can I have a free sample?","e1t":"Ücretsiz bir örnek alabilir miyim?","e2":"The doctor took a blood sample.","e2t":"Doktor kan örneği aldı."},{"w":"sand","tr":"kum","te":"Noun","tt":"İsim","de":"Very small grains of rock found on beaches","dt":"Plajlarda bulunan çok küçük kaya taneleri","e1":"The children are playing in the sand.","e1t":"Çocuklar kumda oynuyorlar.","e2":"I have sand in my shoes.","e2t":"Ayakkabılarımda kum var."},{"w":"sandwich","tr":"sandviç","te":"Noun","tt":"İsim","de":"Two pieces of bread with food between them","dt":"Arasında yiyecek olan iki parça ekmek","e1":"I had a cheese sandwich for lunch.","e1t":"Öğle yemeğinde peynirli sandviç yedim.","e2":"Make me a sandwich, please.","e2t":"Bana bir sandviç yap lütfen."},{"w":"satisfaction","tr":"memnuniyet","te":"Noun","tt":"İsim","de":"A feeling of pleasure when you get what you want","dt":"İstediğinizi aldığınızda duyulan haz hissi","e1":"Customer satisfaction is very important.","e1t":"Müşteri memnuniyeti çok önemlidir.","e2":"He felt a sense of satisfaction.","e2t":"Bir memnuniyet duygusu hissetti."},{"w":"sauce","tr":"sos","te":"Noun","tt":"İsim","de":"A liquid substance served with food","dt":"Yemekle birlikte servis edilen sıvı madde","e1":"I like tomato sauce on my pasta.","e1t":"Makarnamda domates sosunu severim.","e2":"This sauce is very spicy.","e2t":"Bu sos çok baharatlı."},{"w":"save","tr":"kaydetmek / kurtarmak","te":"Verb","tt":"Fiil","de":"To keep safe or to store data","dt":"Güvende tutmak veya veriyi depolamak","e1":"He saved the boy from the river.","e1t":"Çocuğu nehirden kurtardı.","e2":"Don't forget to save your file.","e2t":"Dosyanı kaydetmeyi unutma."},{"w":"scale","tr":"ölçek","te":"Noun","tt":"İsim","de":"A system of measurement or a weighing machine","dt":"Ölçüm sistemi veya tartı aleti","e1":"On a scale of 1 to 10, how is the pain?","e1t":"1'den 10'a kadar olan ölçekte ağrı nasıl?","e2":"Step on the scales, please.","e2t":"Tartıya çıkın lütfen."},{"w":"scene","tr":"sahne","te":"Noun","tt":"İsim","de":"A part of a play or a view","dt":"Bir oyunun parçası veya bir manzara","e1":"This is my favorite scene in the movie.","e1t":"Bu filmdeki en sevdiğim sahne.","e2":"The scene of the accident was chaotic.","e2t":"Kaza mahalli (sahnesi) kaotikti."},{"w":"science","tr":"bilim","te":"Noun","tt":"İsim","de":"The study of the natural world","dt":"Doğal dünyanın incelenmesi","e1":"He is interested in space science.","e1t":"Uzay bilimiyle ilgileniyor.","e2":"Science can explain many things.","e2t":"Bilim birçok şeyi açıklayabilir."},{"w":"scientist","tr":"bilim insanı","te":"Noun","tt":"İsim","de":"A person who studies or works in science","dt":"Bilim alanında çalışan veya okuyan kişi","e1":"Scientists are looking for a cure.","e1t":"Bilim insanları bir tedavi arıyorlar.","e2":"Einstein was a brilliant scientist.","e2t":"Einstein dahi bir bilim insanıydı."},{"w":"search","tr":"aramak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look carefully for something","dt":"Bir şeyi dikkatlice aramak","e1":"I am searching for my keys.","e1t":"Anahtarlarımı arıyorum.","e2":"He did an internet search.","e2t":"İnternet araması yaptı."},{"w":"season","tr":"mevsim / sezon","te":"Noun","tt":"İsim","de":"One of the four parts of the year","dt":"Yılın dört bölümünden biri","e1":"Summer is my favorite season.","e1t":"Yaz en sevdiğim mevsimdir.","e2":"The new season starts next month.","e2t":"Yeni sezon gelecek ay başlıyor."},{"w":"seat","tr":"koltuk","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something to sit on","dt":"Oturulacak şey","e1":"Please take a seat.","e1t":"Lütfen oturun (bir koltuk alın).","e2":"Is this seat taken?","e2t":"Bu koltuk dolu mu?"},{"w":"secret","tr":"sır","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something that is kept hidden","dt":"Gizli tutulan şey","e1":"Can you keep a secret?","e1t":"Bir sır tutabilir miyim?","e2":"This is a secret location.","e2t":"Burası gizli bir konum."},{"w":"security","tr":"güvenlik","te":"Noun","tt":"İsim","de":"Protection against danger or theft","dt":"Tehlike veya hırsızlığa karşı koruma","e1":"There is tight security at the airport.","e1t":"Havaalanında sıkı güvenlik var.","e2":"He works in security.","e2t":"Güvenlikte çalışıyor."},{"w":"seek","tr":"aramak","te":"Verb","tt":"Fiil","de":"To try to find or get something","dt":"Bir şeyi bulmaya veya elde etmeye çalışmak","e1":"You should seek advice from a doctor.","e1t":"Bir doktordan tavsiye almalısın (aramalısın).","e2":"They are seeking a new home.","e2t":"Yeni bir ev arıyorlar."},{"w":"seem","tr":"görünmek","te":"Verb","tt":"Fiil","de":"To give the impression of being","dt":"Öyleymiş izlenimi vermek","e1":"You seem tired today.","e1t":"Bugün yorgun görünüyorsun.","e2":"It seems like a good idea.","e2t":"İyi bir fikir gibi görünüyor."},{"w":"select","tr":"seçmek","te":"Verb","tt":"Fiil","de":"To choose someone or something","dt":"Birini veya bir şeyi seçmek","e1":"Please select a language.","e1t":"Lütfen bir dil seçin.","e2":"He was selected for the team.","e2t":"Takım için seçildi."},{"w":"selection","tr":"seçim","te":"Noun","tt":"İsim","de":"The act of choosing or a variety","dt":"Seçme eylemi veya çeşitlilik","e1":"The shop has a wide selection of shoes.","e1t":"Dükkanın geniş bir ayakkabı seçeneği (seçkisi) var.","e2":"Success depends on your selection.","e2t":"Başarı seçimine bağlıdır."},{"w":"self","tr":"benlik","te":"Noun","tt":"İsim","de":"A person's essential being","dt":"Bir kişinin temel varlığı","e1":"He has a strong sense of self.","e1t":"Güçlü bir benlik duygusu var.","e2":"Always be your true self.","e2t":"Her zaman gerçek kendin (benliğin) ol."},{"w":"send","tr":"göndermek","te":"Verb","tt":"Fiil","de":"To cause to go or be taken to a place","dt":"Bir yere gitmesini veya götürülmesini sağlamak","e1":"Send me an email.","e1t":"Bana bir e","e2":"posta gönder.","e2t":"I will send the package tomorrow."},{"w":"senior","tr":"kıdemli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Older or higher in rank","dt":"Daha yaşlı veya rütbece daha yüksek","e1":"He is a senior manager.","e1t":"O kıdemli bir müdürdür.","e2":"Discounts are available for senior citizens.","e2t":"Yaşlı (kıdemli) vatandaşlar için indirimler mevcuttur."},{"w":"sense","tr":"duygu / his","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling or one of the five physical powers","dt":"Bir duygu veya beş fiziksel güçten biri","e1":"Dogs have a great sense of smell.","e1t":"Köpeklerin harika bir koku alma duyusu vardır.","e2":"I sensed that something was wrong.","e2t":"Bir şeylerin yanlış olduğunu hissettim."},{"w":"serious","tr":"ciddi","te":"Adjective","tt":"Sıfat","de":"Solemn or involving danger","dt":"Ağırbaşlı veya tehlike içeren","e1":"This is a serious problem.","e1t":"Bu ciddi bir sorun.","e2":"Are you serious?","e2t":"Ciddi misin?"},{"w":"session","tr":"oturum","te":"Noun","tt":"İsim","de":"A period of time for an activity","dt":"Bir aktivite için ayrılan zaman dilimi","e1":"The training session lasted two hours.","e1t":"Eğitim oturumu iki saat sürdü.","e2":"We had a long recording session.","e2t":"Uzun bir kayıt oturumumuz oldu."},{"w":"set","tr":"ayarlamak / set","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put in a place or a group of things","dt":"Bir yere koymak veya bir dizi şey","e1":"Set the table, please.","e1t":"Lütfen masayı kur (ayarla).","e2":"I bought a new set of tools.","e2t":"Yeni bir takım (set) alet aldım."},{"w":"setting","tr":"ayar / ortam","te":"Noun","tt":"İsim","de":"The surroundings or a control on a machine","dt":"Çevre veya bir makine üzerindeki kontrol","e1":"You can change the language in the settings.","e1t":"Ayarlardan dili değiştirebilirsin.","e2":"It was a beautiful setting for a wedding.","e2t":"Düğün için güzel bir ortam (mekan) idi."},{"w":"settle","tr":"yerleşmek","te":"Verb","tt":"Fiil","de":"To go and live somewhere permanently","dt":"Bir yere kalıcı olarak yaşamaya gitmek","e1":"They decided to settle in Izmir.","e1t":"İzmir'e yerleşmeye karar verdiler.","e2":"Let's settle this argument.","e2t":"Bu tartışmayı halledelim (çözelim)."},{"w":"seven","tr":"yedi","te":"Number","tt":"Sayı","de":"The number after six","dt":"Altıdan sonraki sayı","e1":"I have seven dollars.","e1t":"Yedi dolarım var.","e2":"There are seven days in a week.","e2t":"Bir haftada yedi gün vardır."},{"w":"several","tr":"birkaç","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"More than two but not many","dt":"İkiden fazla ama çok değil","e1":"I have several questions.","e1t":"Birkaç sorum var.","e2":"He visited several countries.","e2t":"Birkaç ülkeyi ziyaret etti."},{"w":"shade","tr":"gölge","te":"Noun/Verb","tt":"İsim/Fiil","de":"Darkness caused by light being blocked","dt":"Işığın engellenmesiyle oluşan karanlık","e1":"Let's sit in the shade.","e1t":"Gölgede oturalım.","e2":"The trees provide shade.","e2t":"Ağaçlar gölge sağlar."},{"w":"shadow","tr":"gölge","te":"Noun","tt":"İsim","de":"A dark area made by an object in light","dt":"Işıktaki bir nesnenin oluşturduğu karanlık alan","e1":"I saw a shadow on the wall.","e1t":"Duvarda bir gölge gördüm.","e2":"The dog was chasing its shadow.","e2t":"Köpek gölgesini kovalıyordu."},{"w":"shake","tr":"sallamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move quickly up and down or side to side","dt":"Hızla yukarı aşağı veya yanlara hareket etmek","e1":"Shake the bottle before opening.","e1t":"Açmadan önce şişeyi çalkala (salla).","e2":"They shook hands.","e2t":"El sıkıştılar."},{"w":"shall","tr":"","te":"ecek/","tt":"acak","de":"Modal Verb","dt":"Used for future actions or offers","e1":"Gelecek eylemler veya teklifler için kullanılır","e1t":"Shall we go?","e2":"Gidelim mi?","e2t":"I shall never forget this day."},{"w":"shape","tr":"şekil","te":"Noun/Verb","tt":"İsim/Fiil","de":"The external form of something","dt":"Bir şeyin dış formu","e1":"What shape is the table?","e1t":"Masanın şekli ne?","e2":"Exercise helps you stay in shape.","e2t":"Egzersiz formda (şekilde) kalmana yardımcı olur."},{"w":"share","tr":"paylaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give a part of something to others","dt":"Bir şeyin bir kısmını başkalarına vermek","e1":"Can I share your umbrella?","e1t":"Şemsiyeni paylaşabilir miyim?","e2":"He posted a share on social media.","e2t":"Sosyal medyada bir paylaşım yaptı."},{"w":"sharp","tr":"keskin","te":"Adjective","tt":"Sıfat","de":"Having a thin edge for cutting","dt":"Kesmek için ince bir kenarı olan","e1":"This knife is very sharp.","e1t":"Bu bıçak çok keskin.","e2":"There is a sharp turn ahead.","e2t":"İleride keskin bir viraj var."},{"w":"she","tr":"o (kadın)","te":"Pronoun","tt":"Zamir","de":"A female person","dt":"Bir kadın","e1":"She is my sister.","e1t":"O benim kız kardeşim.","e2":"Does she speak English?","e2t":"O İngilizce konuşuyor mu?"},{"w":"sheet","tr":"çarşaf / kağıt","te":"Noun","tt":"İsim","de":"A piece of cloth for a bed or a piece of paper","dt":"Yatak örtüsü veya bir parça kağıt","e1":"I need a clean sheet for the bed.","e1t":"Yatak için temiz bir çarşaf gerekiyor.","e2":"Take a sheet of paper.","e2t":"Bir kağıt yaprağı al."},{"w":"shelf","tr":"raf","te":"Noun","tt":"İsim","de":"A flat board for holding things","dt":"Eşyaları tutmak için düz tahta","e1":"Put the books on the shelf.","e1t":"Kitapları rafa koy.","e2":"The top shelf is too high.","e2t":"Üst raf çok yüksek."},{"w":"shell","tr":"kabuk","te":"Noun","tt":"İsim","de":"The hard outer covering of something","dt":"Bir şeyin sert dış örtüsü","e1":"I found a beautiful shell on the beach.","e1t":"Plajda güzel bir kabuk buldum.","e2":"The egg shell is broken.","e2t":"Yumurta kabuğu kırılmış."},{"w":"shine","tr":"parlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give out or reflect light","dt":"Işık vermek veya yansıtmak","e1":"The sun is shining.","e1t":"Güneş parlıyor.","e2":"I need to shine my shoes.","e2t":"Ayakkabılarımı parlatmam gerekiyor."},{"w":"shock","tr":"şok","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden upsetting or surprising event","dt":"Ani üzücü veya şaşırtıcı olay","e1":"The news came as a shock.","e1t":"Haberler şok etkisi yarattı.","e2":"I was shocked by the price.","e2t":"Fiyat karşısında şok oldum."},{"w":"shoe","tr":"ayakkabı","te":"Noun","tt":"İsim","de":"A covering for the foot","dt":"Ayak için örtü","e1":"Your shoes are dirty.","e1t":"Ayakkabıların kirli.","e2":"Take off your shoes.","e2t":"Ayakkabılarını çıkar."},{"w":"shoot","tr":"ateş etmek / çekim yapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fire a gun or take a photo/film","dt":"Silah patlatmak veya fotoğraf/film çekmek","e1":"He learned how to shoot.","e1t":"Ateş etmeyi öğrendi.","e2":"They are shooting a movie.","e2t":"Bir film çekiyorlar."},{"w":"shoulder","tr":"omuz","te":"Noun","tt":"İsim","de":"The joint between the arm and the neck","dt":"Kol ve boyun arasındaki eklem","e1":"He carried the child on his shoulders.","e1t":"Çocuğu omuzlarında taşıdı.","e2":"My shoulder hurts.","e2t":"Omuzum ağrıyor."},{"w":"shower","tr":"duş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A brief wash or light rain","dt":"Kısa bir yıkanma veya hafif yağmur","e1":"I take a shower every morning.","e1t":"Her sabah duş alırım.","e2":"There was a sudden rain shower.","e2t":"Ani bir sağanak (duş şeklinde) yağmur vardı."},{"w":"shut","tr":"kapatmak","te":"Verb/Adjective","tt":"To close or being closed","de":"Kapatmak veya kapalı olma durumu","dt":"Shut the door, please.","e1":"Lütfen kapıyı kapat.","e1t":"The windows are shut.","e2":"Pencereler kapalı.","e2t":""},{"w":"shy","tr":"utangaç","te":"Adjective","tt":"Sıfat","de":"Nervous or uncomfortable with people","dt":"İnsanlarla birlikteyken gergin veya rahatsız","e1":"He is a very shy child.","e1t":"O çok utangaç bir çocuktur.","e2":"Don't be shy, come in.","e2t":"Utanma, içeri gir."},{"w":"sick","tr":"hasta","te":"Adjective","tt":"Sıfat","de":"Not well or healthy","dt":"İyi veya sağlıklı olmama durumu","e1":"I feel sick today.","e1t":"Bugün hasta hissediyorum.","e2":"He stayed home because he was sick.","e2t":"Hasta olduğu için evde kaldı."},{"w":"side","tr":"taraf","te":"Noun","tt":"İsim","de":"A position or part away from the center","dt":"Merkezden uzak bir konum veya parça","e1":"The shop is on the other side of the street.","e1t":"Dükkan sokağın diğer tarafında.","e2":"Which side are you on?","e2t":"Hangi taraftasın?"},{"w":"sight","tr":"manzara / görüş","te":"Noun","tt":"İsim","de":"The ability to see or something seen","dt":"Görme yeteneği veya görülen şey","e1":"His sight is getting worse.","e1t":"Görüşü kötüleşiyor.","e2":"The sunset was a beautiful sight.","e2t":"Gün batımı güzel bir manzaraydı."},{"w":"sign","tr":"işaret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A mark, signal, or to write one's name","dt":"Bir işaret, sinyal veya isim yazmak (imzalamak)","e1":"Follow the road signs.","e1t":"Yol işaretlerini takip et.","e2":"Please sign here.","e2t":"Lütfen burayı imzalayın."},{"w":"significant","tr":"önemli","te":"Adjective","tt":"Sıfat","de":"Important or noticeable","dt":"Önemli veya fark edilebilir","e1":"There is a significant difference.","e1t":"Önemli bir fark var.","e2":"This is a significant event.","e2t":"Bu önemli bir olaydır."},{"w":"silence","tr":"sessizlik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A complete lack of noise","dt":"Tam bir gürültü yokluğu","e1":"Silence, please!","e1t":"Sessizlik, lütfen!","e2":"They sat in silence.","e2t":"Sessizlik içinde oturdular."},{"w":"silver","tr":"gümüş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A shiny grey","dt":"white precious metal","e1":"Parlak gri","e1t":"beyaz değerli metal","e2":"This spoon is made of silver.","e2t":"Bu kaşık gümüşten yapılmıştır."},{"w":"similar","tr":"benzer","te":"Adjective","tt":"Sıfat","de":"Looking or being almost the same","dt":"Neredeyse aynı görünme veya olma","e1":"My car is similar to yours.","e1t":"Benim arabam seninkine benzer.","e2":"We have similar interests.","e2t":"Benzer ilgi alanlarımız var."},{"w":"since","tr":"","te":"den beri","tt":"Preposition/Conjunction","de":"From a particular time in the past until now","dt":"Geçmişteki belirli bir zamandan şimdiye kadar","e1":"I have lived here since 2010.","e1t":"2010'dan beri burada yaşıyorum.","e2":"It has been a long time since we met.","e2t":"Görüştüğümüzden beri uzun zaman oldu."},{"w":"singer","tr":"şarkıcı","te":"Noun","tt":"İsim","de":"A person who sings","dt":"Şarkı söyleyen kişi","e1":"She is a famous opera singer.","e1t":"O ünlü bir opera şarkıcısıdır.","e2":"Who is your favorite singer?","e2t":"En sevdiğin şarkıcı kim?"},{"w":"single","tr":"tek","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Only one or not married","dt":"Sadece bir tane veya evli olmayan","e1":"I'd like a single room, please.","e1t":"Tek kişilik bir oda rica ediyorum.","e2":"He is still single.","e2t":"O hâlâ bekâr."},{"w":"sir","tr":"beyefendi","te":"Noun","tt":"İsim","de":"A polite way to address a man","dt":"Bir erkeğe hitap etmenin nazik yolu","e1":"Excuse me, sir!","e1t":"Affedersiniz beyefendi!","e2":"Yes, sir, I understand.","e2t":"Evet efendim, anlıyorum."},{"w":"situation","tr":"durum","te":"Noun","tt":"İsim","de":"A set of things that are happening at a time","dt":"Bir zamanda gerçekleşen olaylar bütünü","e1":"It is a difficult situation.","e1t":"Zor bir durum.","e2":"We need to handle the situation carefully.","e2t":"Durumu dikkatlice yönetmemiz gerekiyor."},{"w":"size","tr":"boyut","te":"Noun","tt":"İsim","de":"How big or small something is","dt":"Bir şeyin ne kadar büyük veya küçük olduğu","e1":"What size do you wear?","e1t":"Kaç beden (boyut) giyiyorsunuz?","e2":"The size of the room is perfect.","e2t":"Odanın boyutu mükemmel."},{"w":"skill","tr":"beceri","te":"Noun","tt":"İsim","de":"The ability to do something well","dt":"Bir şeyi iyi yapma yeteneği","e1":"You need special skills for this job.","e1t":"Bu iş için özel becerilere ihtiyacın var.","e2":"Typing is a useful skill.","e2t":"Yazı yazmak (klavye) yararlı bir beceridir."},{"w":"slide","tr":"kaymak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move smoothly along a surface","dt":"Bir yüzey boyunca pürüzsüzce hareket etmek","e1":"The kids love the slide at the park.","e1t":"Çocuklar parktaki kaydırağı (kaymayı) seviyorlar.","e2":"Be careful, the floor is wet and you might slide.","e2t":"Dikkat et, zemin ıslak ve kayabilirsin."},{"w":"smart","tr":"zeki","te":"Adjective","tt":"Sıfat","de":"Intelligent or neat in appearance","dt":"Zeki veya görünüşte düzenli","e1":"He is a very smart student.","e1t":"O çok zeki bir öğrencidir.","e2":"You look very smart in that suit.","e2t":"O takım elbise içinde çok şık (derli toplu) görünüyorsun."},{"w":"smile","tr":"gülümsemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a happy expression with the mouth","dt":"Ağızla mutlu bir ifade yapmak","e1":"She has a beautiful smile.","e1t":"Güzel bir gülümsemesi var.","e2":"Smile for the camera!","e2t":"Kamera için gülümse!"},{"w":"smoke","tr":"duman / sigara içmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Grey gas from fire or to use a cigarette","dt":"Ateşten çıkan gri gaz veya sigara kullanmak","e1":"There is a lot of smoke in the kitchen.","e1t":"Mutfakta çok fazla duman var.","e2":"You should stop smoking.","e2t":"Sigarayı bırakmalısın."},{"w":"smooth","tr":"pürüzsüz","te":"Adjective","tt":"Sıfat","de":"Having a flat surface without lumps","dt":"Topaksız, düz bir yüzeye sahip olma","e1":"The baby's skin is so smooth.","e1t":"Bebeğin cildi çok pürüzsüz.","e2":"The flight was very smooth.","e2t":"Uçuş çok sarsıntısız (pürüzsüz) geçti."},{"w":"snake","tr":"yılan","te":"Noun","tt":"İsim","de":"A long thin reptile with no legs","dt":"Bacaksız, uzun ince sürüngen","e1":"I am afraid of snakes.","e1t":"Yılanlardan korkarım.","e2":"Some snakes are dangerous.","e2t":"Bazı yılanlar tehlikelidir."},{"w":"soap","tr":"sabun","te":"Noun","tt":"İsim","de":"A substance used with water for washing","dt":"Yıkama için suyla kullanılan madde","e1":"Wash your hands with soap.","e1t":"Ellerinizi sabunla yıkayın.","e2":"I need to buy some liquid soap.","e2t":"Biraz sıvı sabun almam gerekiyor."},{"w":"soccer","tr":"futbol","te":"Noun","tt":"İsim","de":"A game played with a ball (American English)","dt":"Topla oynanan bir oyun (Amerikan İngilizcesi)","e1":"Soccer is popular in the USA.","e1t":"Futbol ABD'de popülerdir.","e2":"We play soccer every weekend.","e2t":"Her hafta sonu futbol oynuyoruz."},{"w":"social","tr":"sosyal","te":"Adjective","tt":"Sıfat","de":"Relating to society or meeting people","dt":"Toplumla veya insanlarla tanışmakla ilgili","e1":"Man is a social animal.","e1t":"İnsan sosyal bir hayvandır.","e2":"Do you have any social media accounts?","e2t":"Hiç sosyal medya hesabın var mı?"},{"w":"society","tr":"toplum","te":"Noun","tt":"İsim","de":"People living together in a community","dt":"Bir topluluk içinde birlikte yaşayan insanlar","e1":"We live in a modern society.","e1t":"Modern bir toplumda yaşıyoruz.","e2":"Technology is changing our society.","e2t":"Teknoloji toplumumuzu değiştiriyor."},{"w":"sock","tr":"çorap","te":"Noun","tt":"İsim","de":"A piece of clothing for the foot","dt":"Ayak için bir giysi parçası","e1":"I can't find my other sock.","e1t":"Diğer çorabımı bulamıyorum.","e2":"Wear warm socks in winter.","e2t":"Kışın sıcak tutan çoraplar giy."},{"w":"soft","tr":"yumuşak","te":"Adjective","tt":"Sıfat","de":"Not hard or firm","dt":"Sert veya katı olmayan","e1":"This pillow is very soft.","e1t":"Bu yastık çok yumuşak.","e2":"I like soft music.","e2t":"Hafif (yumuşak) müziği severim."},{"w":"soil","tr":"toprak","te":"Noun","tt":"İsim","de":"The top layer of earth where plants grow","dt":"Bitkilerin yetiştiği yerin en üst katmanı","e1":"The soil in this garden is very rich.","e1t":"Bu bahçedeki toprak çok verimli.","e2":"Plants need good soil to grow.","e2t":"Bitkilerin büyümek için iyi toprağa ihtiyacı vardır."},{"w":"soldier","tr":"asker","te":"Noun","tt":"İsim","de":"A person who serves in an army","dt":"Orduda görev yapan kişi","e1":"He wants to be a soldier.","e1t":"Asker olmak istiyor.","e2":"The soldiers followed the orders.","e2t":"Askerler emirlere uydular."},{"w":"solve","tr":"çözmek","te":"Verb","tt":"Fiil","de":"To find an answer to a problem","dt":"Bir soruna cevap bulmak","e1":"Can you solve this puzzle?","e1t":"Bu bulmacayı çözebilir misin?","e2":"We need to solve the problem quickly.","e2t":"Sorunu hızlıca çözmemiz gerekiyor."},{"w":"someone","tr":"birisi","te":"Pronoun","tt":"Zamir","de":"A person who is not known or named","dt":"Bilinmeyen veya ismi verilmeyen kişi","e1":"Someone is knocking on the door.","e1t":"Birisi kapıyı çalıyor.","e2":"I need someone to help me.","e2t":"Bana yardım edecek birine ihtiyacım var."},{"w":"something","tr":"bir şey","te":"Pronoun","tt":"Zamir","de":"A thing that is not known or named","dt":"Bilinmeyen veya ismi verilmeyen şey","e1":"Something is wrong with my car.","e1t":"Arabamda bir şeyler yanlış.","e2":"I want to say something.","e2t":"Bir şey söylemek istiyorum."},{"w":"somewhere","tr":"bir yerde","te":"Adverb","tt":"Zarf","de":"In or to a place that is not known","dt":"Bilinmeyen bir yerde veya yere","e1":"I lost my keys somewhere.","e1t":"Anahtarlarımı bir yerde kaybettim.","e2":"Let's go somewhere quiet.","e2t":"Sessiz bir yere gidelim."},{"w":"sore","tr":"ağrılı","te":"Adjective","tt":"Sıfat","de":"Painful and uncomfortable","dt":"Ağrılı ve rahatsız edici","e1":"I have a sore throat.","e1t":"Boğazım ağrıyor (ağrılı boğazım var).","e2":"My muscles are sore after exercise.","e2t":"Egzersizden sonra kaslarım ağrıyor."},{"w":"sort","tr":"tür","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of something or to arrange things","dt":"Bir şeyin türü veya şeyleri düzenlemek","e1":"What sort of food do you like?","e1t":"Ne tür yemek seversin?","e2":"Sort the files by date.","e2t":"Dosyaları tarihe göre sırala."},{"w":"sound","tr":"ses","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that you can hear","dt":"Duyabildiğiniz bir şey","e1":"I heard a strange sound.","e1t":"Garip bir ses duydum.","e2":"That sounds like a good idea.","e2t":"Kulağa iyi bir fikir gibi geliyor."},{"w":"speaker","tr":"konuşmacı","te":"Noun","tt":"İsim","de":"A person who speaks or a device for sound","dt":"Konuşan kişi veya ses veren cihaz (hoparlör)","e1":"He is a great public speaker.","e1t":"O harika bir topluluk önünde konuşmacıdır.","e2":"One of the speakers is broken.","e2t":"Hoparlörlerden biri bozuk."},{"w":"special","tr":"özel","te":"Adjective","tt":"Sıfat","de":"Better, greater, or different from usual","dt":"Olağandan daha iyi, daha büyük veya farklı","e1":"This is a special occasion.","e1t":"Bu özel bir durumdur.","e2":"You are a very special person.","e2t":"Çok özel bir insansın."},{"w":"specialist","tr":"uzman","te":"Noun","tt":"İsim","de":"A person who is an expert in a subject","dt":"Bir konuda uzman olan kişi","e1":"You should see a heart specialist.","e1t":"Bir kalp uzmanına görünmelisin.","e2":"She is a specialist in computer security.","e2t":"O, bilgisayar güvenliği konusunda uzmandır."},{"w":"speech","tr":"konuşma","te":"Noun","tt":"İsim","de":"A formal talk or the ability to speak","dt":"Resmi bir konuşma veya konuşma yeteneği","e1":"He gave a long speech at the wedding.","e1t":"Düğünde uzun bir konuşma yaptı.","e2":"Freedom of speech is a right.","e2t":"Konuşma özgürlüğü bir haktır."},{"w":"speed","tr":"hız","te":"Noun/Verb","tt":"İsim/Fiil","de":"How fast something moves","dt":"Bir şeyin ne kadar hızlı hareket ettiği","e1":"What is the speed of light?","e1t":"Işık hızı nedir?","e2":"Don't exceed the speed limit.","e2t":"Hız sınırını aşma."},{"w":"spend","tr":"harcamak","te":"Verb","tt":"Fiil","de":"To use money or time","dt":"Para veya zaman kullanmak","e1":"I spend a lot of money on books.","e1t":"Kitaplara çok para harcarım.","e2":"How do you spend your weekends?","e2t":"Hafta sonlarını nasıl geçirirsin (harcarsın)?"},{"w":"spice","tr":"baharat","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance used to give flavor to food","dt":"Yemeğe lezzet vermek için kullanılan madde","e1":"I like adding spices to my food.","e1t":"Yemeklerime baharat eklemeyi severim.","e2":"Black pepper is a common spice.","e2t":"Karabiber yaygın bir baharattır."},{"w":"spider","tr":"örümcek","te":"Noun","tt":"İsim","de":"A small animal with eight legs","dt":"Sekiz bacaklı küçük hayvan","e1":"There is a spider on the wall.","e1t":"Duvarda bir örümcek var.","e2":"Most spiders are harmless.","e2t":"Çoğu örümcek zararsızdır."},{"w":"spirit","tr":"ruh","te":"Noun","tt":"İsim","de":"The non","dt":"physical part of a person; mood","e1":"Bir kişinin fiziksel olmayan kısmı; ruh hali","e1t":"He has a strong team spirit.","e2":"Güçlü bir takım ruhu var.","e2t":"The spirit of the law is important."},{"w":"stage","tr":"sahne / aşama","te":"Noun/Verb","tt":"İsim/Fiil","de":"A raised floor or a period in a process","dt":"Yükseltilmiş zemin veya bir süreçteki dönem","e1":"The band is on the stage.","e1t":"Grup sahnede.","e2":"We are in the final stage of the project.","e2t":"Projenin son aşamasındayız."},{"w":"stair","tr":"basamak","te":"Noun","tt":"İsim","de":"A set of steps from one floor to another","dt":"Bir kattan diğerine giden adımlar seti","e1":"He ran up the stairs.","e1t":"Merdivenlerden yukarı koştu.","e2":"Be careful on the bottom stair.","e2t":"En alt basamakta dikkatli ol."},{"w":"stamp","tr":"pul","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of paper for mail","dt":"Posta için kullanılan küçük kağıt parçası","e1":"Don't forget to put a stamp on the envelope.","e1t":"Zarfın üzerine pul yapıştırmayı unutma.","e2":"He collects rare stamps.","e2t":"Nadir pulları topluyor."},{"w":"standard","tr":"standart","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A level of quality or a regular rule","dt":"Kalite seviyesi veya düzenli bir kural","e1":"The school has high standards.","e1t":"Okulun yüksek standartları var.","e2":"This is the standard procedure.","e2t":"Bu standart prosedürdür."},{"w":"statement","tr":"ifade","te":"Noun","tt":"İsim","de":"Something that someone says or writes formally","dt":"Birinin resmi olarak söylediği veya yazdığı şey","e1":"The witness gave a statement to the police.","e1t":"Tanık polise bir ifade verdi.","e2":"Read the following statement carefully.","e2t":"Aşağıdaki ifadeyi dikkatlice oku."},{"w":"status","tr":"durum","te":"Noun","tt":"İsim","de":"The official position or condition of someone","dt":"Birinin resmi konumu veya durumu","e1":"What is your marital status?","e1t":"Medeni durumunuz nedir?","e2":"He has a high social status.","e2t":"Yüksek bir sosyal statüsü var."},{"w":"stay","tr":"kalmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remain in a place","dt":"Bir yerde kalmak","e1":"I want to stay at home today.","e1t":"Bugün evde kalmak istiyorum.","e2":"How long was your stay in London?","e2t":"Londra'daki kalış süreniz ne kadardı?"},{"w":"steal","tr":"çalmak","te":"Verb","tt":"Fiil","de":"To take something without permission","dt":"İzin almadan bir şeyi almak","e1":"Someone stole my bike.","e1t":"Birisi bisikletimi çaldı.","e2":"It is a crime to steal.","e2t":"Çalmak bir suçtur."},{"w":"step","tr":"adım","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act of lifting and putting down your foot","dt":"Ayağınızı kaldırıp yere koyma eylemi","e1":"Take one step forward.","e1t":"Bir adım ileri at.","e2":"We must follow the steps of the process.","e2t":"Sürecin adımlarını takip etmeliyiz."},{"w":"stone","tr":"taş","te":"Noun","tt":"İsim","de":"Hard solid material found in the ground","dt":"Yer altında bulunan sert katı malzeme","e1":"The house is built of stone.","e1t":"Ev taştan yapılmıştır.","e2":"He threw a stone into the water.","e2t":"Suya bir taş attı."},{"w":"straight","tr":"düz","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not curving or bending","dt":"Kıvrılmayan veya bükülmeyen","e1":"Go straight and turn left.","e1t":"Düz git ve sola dön.","e2":"She has straight hair.","e2t":"Düz saçı var."},{"w":"strange","tr":"garip","te":"Adjective","tt":"Sıfat","de":"Unusual or surprising","dt":"Olağandışı veya şaşırtıcı","e1":"I heard a strange noise.","e1t":"Garip bir ses duydum.","e2":"He is a strange man.","e2t":"O garip bir adamdır."},{"w":"stranger","tr":"yabancı","te":"Noun","tt":"İsim","de":"A person you do not know","dt":"Tanımadığınız kişi","e1":"Don't talk to strangers.","e1t":"Yabancılarla konuşma.","e2":"I felt like a stranger in the city.","e2t":"Şehirde bir yabancı gibi hissettim."},{"w":"strategy","tr":"strateji","te":"Noun","tt":"İsim","de":"A plan of action designed to achieve a goal","dt":"Bir hedefe ulaşmak için tasarlanmış eylem planı","e1":"We need a new marketing strategy.","e1t":"Yeni bir pazarlama stratejisine ihtiyacımız var.","e2":"What is your business strategy?","e2t":"İş stratejin nedir?"},{"w":"strength","tr":"güç","te":"Noun","tt":"İsim","de":"The quality of being physically strong","dt":"Fiziksel olarak güçlü olma özelliği","e1":"He has great physical strength.","e1t":"Büyük bir fiziksel gücü var.","e2":"Exercise increases your strength.","e2t":"Egzersiz gücünüzü artırır."},{"w":"struggle","tr":"mücadele","te":"Verb/Noun","tt":"Fiil/İsim","de":"To try very hard to do something difficult","dt":"Zor bir şeyi yapmak için çok çaba sarf etmek","e1":"He struggled to carry the heavy bag.","e1t":"Ağır çantayı taşımak için mücadele etti.","e2":"It was a long struggle for independence.","e2t":"Bağımsızlık için uzun bir mücadeleydi."},{"w":"subject","tr":"konu","te":"Noun","tt":"İsim","de":"The thing that is being talked or written about","dt":"Hakkında konuşulan veya yazılan şey","e1":"What is your favorite subject at school?","e1t":"Okulda en sevdiğin ders (konu) hangisi?","e2":"The subject of the meeting is sales.","e2t":"Toplantının konusu satışlar."},{"w":"succeed","tr":"başarmak","te":"Verb","tt":"Fiil","de":"To achieve something that you wanted","dt":"İstediğiniz bir şeyi başarmak","e1":"If you work hard, you will succeed.","e1t":"Eğer sıkı çalışırsan başarırsın.","e2":"He finally succeeded in passing the exam.","e2t":"Sonunda sınavı geçmeyi başardı."},{"w":"success","tr":"başarı","te":"Noun","tt":"İsim","de":"The achievement of an aim or purpose","dt":"Bir amacın veya hedefin gerçekleştirilmesi","e1":"I wish you great success.","e1t":"Sana büyük başarılar dilerim.","e2":"The party was a big success.","e2t":"Parti büyük bir başarıydı."},{"w":"successful","tr":"başarılı","te":"Adjective","tt":"Sıfat","de":"Achieving the result you wanted","dt":"İstediğiniz sonucu elde etme","e1":"She is a successful businesswoman.","e1t":"O başarılı bir iş kadınıdır.","e2":"The operation was successful.","e2t":"Operasyon başarılıydı."},{"w":"such","tr":"böyle","te":"Determiner/Pronoun","tt":"Belirleyici/Zamir","de":"Of the type previously mentioned","dt":"Daha önce bahsedilen türden","e1":"It was such a beautiful day.","e1t":"Çok güzel bir gündü (böyle güzel bir gündü).","e2":"I have never seen such a big house.","e2t":"Hiç böyle büyük bir ev görmemiştim."},{"w":"suddenly","tr":"aniden","te":"Adverb","tt":"Zarf","de":"Quickly and unexpectedly","dt":"Hızlıca ve beklenmedik bir şekilde","e1":"The lights suddenly went out.","e1t":"Işıklar aniden söndü.","e2":"Suddenly, the car stopped.","e2t":"Aniden araba durdu."},{"w":"suffer","tr":"acı çekmek","te":"Verb","tt":"Fiil","de":"To experience something bad or painful","dt":"Kötü veya acı verici bir şey deneyimlemek","e1":"He suffers from back pain.","e1t":"Sırt ağrısından muzdarip (acı çekiyor).","e2":"Many people suffer in silence.","e2t":"Birçok insan sessizce acı çeker."},{"w":"suggestion","tr":"öneri","te":"Noun","tt":"İsim","de":"An idea or plan put forward for consideration","dt":"Değerlendirilmek üzere sunulan fikir veya plan","e1":"Do you have any suggestions for dinner?","e1t":"Akşam yemeği için bir önerin var mı?","e2":"It was a good suggestion.","e2t":"İyi bir öneriydi."},{"w":"suit","tr":"takım elbise / uymak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A set of outer clothes or to be convenient","dt":"Dış kıyafet takımı veya uygun olmak","e1":"He wore a dark suit to the wedding.","e1t":"Düğüne koyu renk bir takım elbise giydi.","e2":"That color really suits you.","e2t":"Bu renk sana gerçekten yakışıyor (uyuyor)."},{"w":"suitable","tr":"uygun","te":"Adjective","tt":"Sıfat","de":"Right or appropriate for a person or situation","dt":"Bir kişi veya durum için doğru veya uygun olan","e1":"This movie is not suitable for children.","e1t":"Bu film çocuklar için uygun değildir.","e2":"Find a suitable time for the meeting.","e2t":"Toplantı için uygun bir zaman bul."},{"w":"sunrise","tr":"gün doğumu","te":"Noun","tt":"İsim","de":"The time in the morning when the sun appears","dt":"Sabah güneşin göründüğü an","e1":"We watched the sunrise on the beach.","e1t":"Plajda gün doğumunu izledik.","e2":"The sunrise was beautiful.","e2t":"Gün doğumu harikaydı."},{"w":"sunset","tr":"gün batımı","te":"Noun","tt":"İsim","de":"The time in the evening when the sun disappears","dt":"Akşam güneşin kaybolduğu an","e1":"Let's go for a walk at sunset.","e1t":"Gün batımında yürüyüşe çıkalım.","e2":"I love the colors of the sunset.","e2t":"Gün batımının renklerini seviyorum."},{"w":"supply","tr":"tedarik etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To provide something that is needed","dt":"İhtiyaç duyulan bir şeyi sağlamak","e1":"The company supplies office equipment.","e1t":"Şirket ofis ekipmanı tedarik ediyor.","e2":"We have a limited supply of water.","e2t":"Sınırlı bir su kaynağımız (tedariğimiz) var."},{"w":"suppose","tr":"varsaymak","te":"Verb","tt":"Fiil","de":"To think that something is likely to be true","dt":"Bir şeyin muhtemelen doğru olduğunu düşünmek","e1":"I suppose he will be late again.","e1t":"Sanırım (varsayıyorum) yine geç kalacak.","e2":"What are we supposed to do?","e2t":"Ne yapmamız gerekiyor (bekleniyor)?"},{"w":"sure","tr":"emin","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Completely confident that one is right","dt":"Haklı olduğundan tamamen emin olma","e1":"Are you sure about this?","e1t":"Bu konuda emin misin?","e2":"I am sure that I saw him.","e2t":"Onu gördüğümden eminim."},{"w":"surface","tr":"yüzey","te":"Noun","tt":"İsim","de":"The outside part or uppermost layer","dt":"Dış kısım veya en üst katman","e1":"The surface of the table is smooth.","e1t":"Masanın yüzeyi pürüzsüz.","e2":"Don't scratch the surface of the car.","e2t":"Arabanın yüzeyini çizme."},{"w":"surprise","tr":"sürpriz","te":"Noun/Verb","tt":"İsim/Fiil","de":"An unexpected event or to cause wonder","dt":"Beklenmedik olay veya hayret uyandırmak","e1":"What a pleasant surprise!","e1t":"Ne hoş bir sürpriz!","e2":"He surprised her with a gift.","e2t":"Ona bir hediyeyle sürpriz yaptı."},{"w":"system","tr":"sistem","te":"Noun","tt":"İsim","de":"A set of things working together","dt":"Birlikte çalışan şeyler bütünü","e1":"The solar system has eight planets.","e1t":"Güneş sisteminde sekiz gezegen vardır.","e2":"We need a better security system.","e2t":"Daha iyi bir güvenlik sistemine ihtiyacımız var."},{"w":"talkative","tr":"konuşkan","te":"Adjective","tt":"Sıfat","de":"Fond of making conversation","dt":"Sohbet etmeyi seven","e1":"He is a very talkative person.","e1t":"O çok konuşkan biridir.","e2":"My sister is more talkative than me.","e2t":"Kız kardeşim benden daha konuşkandır."},{"w":"teach","tr":"öğretmek","te":"Verb","tt":"Fiil","de":"To give knowledge to someone","dt":"Birine bilgi vermek","e1":"He teaches English at university.","e1t":"Üniversitede İngilizce öğretiyor.","e2":"Can you teach me how to swim?","e2t":"Bana yüzmeyi öğretebilir misin?"},{"w":"tear","tr":"yırtmak / gözyaşı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull something apart or a drop of water from eye","dt":"Bir şeyi parçalara ayırmak veya gözden gelen su damlası","e1":"Don't tear the paper.","e1t":"Kağıdı yırtma.","e2":"She had tears in her eyes.","e2t":"Gözlerinde yaşlar vardı."},{"w":"teenager","tr":"ergen","te":"Noun","tt":"İsim","de":"A person between the ages of 13 and 19","dt":"13 ile 19 yaşları arasındaki kişi","e1":"Most teenagers like video games.","e1t":"Çoğu ergen video oyunlarını sever.","e2":"He is a typical teenager.","e2t":"O tipik bir ergen."},{"w":"telephone","tr":"telefon","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device for speaking to someone far away","dt":"Uzaktaki biriyle konuşmak için kullanılan cihaz","e1":"Answer the telephone, please.","e1t":"Lütfen telefona bak.","e2":"I'll telephone you tomorrow.","e2t":"Seni yarın telefonla arayacağım."},{"w":"telescope","tr":"teleskop","te":"Noun","tt":"İsim","de":"A device used to see things far away","dt":"Uzaktaki şeyleri görmek için kullanılan cihaz","e1":"You can see the moon through a telescope.","e1t":"Teleskopla ayı görebilirsin.","e2":"He bought a new digital telescope.","e2t":"Yeni bir dijital teleskop aldı."},{"w":"television","tr":"televizyon","te":"Noun","tt":"İsim","de":"A device with a screen for watching programs","dt":"Program izlemek için ekranı olan cihaz","e1":"Turn off the television and study.","e1t":"Televizyonu kapat ve ders çalış.","e2":"I don't watch much television.","e2t":"Çok fazla televizyon izlemem."},{"w":"temple","tr":"tapınak","te":"Noun","tt":"İsim","de":"A building used for religious worship","dt":"Dini ibadet için kullanılan bina","e1":"We visited an ancient temple in Japan.","e1t":"Japonya'da antik bir tapınağı ziyaret ettik.","e2":"The temple is very beautiful.","e2t":"Tapınak çok güzel."},{"w":"tent","tr":"çadır","te":"Noun","tt":"İsim","de":"A portable shelter made of fabric","dt":"Kumaştan yapılmış taşınabilir barınak","e1":"We slept in a tent while camping.","e1t":"Kamp yaparken bir çadırda uyuduk.","e2":"Can you help me set up the tent?","e2t":"Çadırı kurmama yardım edebilir misin?"},{"w":"thick","tr":"kalın","te":"Adjective","tt":"Sıfat","de":"Not thin; having a large distance between sides","dt":"İnce olmayan; yanlar arasında büyük mesafe olması","e1":"Wear a thick coat, it's cold.","e1t":"Kalın bir mont giy, hava soğuk.","e2":"The walls are very thick.","e2t":"Duvarlar çok kalın."},{"w":"thin","tr":"ince","te":"Adjective","tt":"Sıfat","de":"Not thick; having a small distance between sides","dt":"Kalın olmayan; yanlar arasında küçük mesafe olması","e1":"He is tall and thin.","e1t":"O uzun ve incedir.","e2":"Slice the bread thin, please.","e2t":"Ekmeği ince dilimle lütfen."},{"w":"thing","tr":"şey","te":"Noun","tt":"İsim","de":"An object, fact, or event","dt":"Nesne, gerçek veya olay","e1":"What is that thing on the table?","e1t":"Masadaki o şey nedir?","e2":"The best thing to do is wait.","e2t":"Yapılacak en iyi şey beklemektir."},{"w":"thought","tr":"düşünce","te":"Noun","tt":"İsim","de":"An idea or opinion produced by thinking","dt":"Düşünerek üretilen fikir veya görüş","e1":"I had a sudden thought.","e1t":"Aniden bir düşünceye kapıldım.","e2":"What are your thoughts on this?","e2t":"Bu konudaki düşüncelerin neler?"},{"w":"thousand","tr":"bin","te":"Number","tt":"Sayı","de":"The number 1,000","dt":"1.000 sayısı","e1":"A thousand people attended the concert.","e1t":"Konsere bin kişi katıldı.","e2":"The laptop costs three thousand dollars.","e2t":"Dizüstü bilgisayar üç bin dolar."},{"w":"through","tr":"içinden","te":"Preposition","tt":"Edat","de":"Moving in one side and out of the other","dt":"Bir taraftan girip diğerinden çıkma","e1":"We drove through the tunnel.","e1t":"Tünelin içinden geçtik.","e2":"I looked through the window.","e2t":"Pencereden (içinden) baktım."},{"w":"throw","tr":"atmak","te":"Verb","tt":"Fiil","de":"To send something through the air with force","dt":"Bir şeyi havada kuvvetle göndermek","e1":"Throw the ball to me.","e1t":"Topu bana at.","e2":"Don't throw garbage on the street.","e2t":"Sokağa çöp atma."},{"w":"thumb","tr":"baş parmak","te":"Noun","tt":"İsim","de":"The short, thick first finger of the human hand","dt":"İnsan elinin kısa, kalın ilk parmağı","e1":"He gave a thumbs","e1t":"up sign.","e2":"Baş parmağıyla onay işareti verdi.","e2t":"I hurt my thumb."},{"w":"tie","tr":"bağlamak / kravat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fasten with a string or a piece of clothing","dt":"Bir iple sabitlemek veya bir giysi parçası","e1":"He tied his shoes.","e1t":"Ayakkabılarını bağladı.","e2":"He wears a suit and tie to work.","e2t":"İşe takım elbise ve kravatla gider."},{"w":"tiger","tr":"kaplan","te":"Noun","tt":"İsim","de":"A large wild cat with orange and black stripes","dt":"Turuncu ve siyah çizgili büyük vahşi kedi","e1":"The tiger is a fast hunter.","e1t":"Kaplan hızlı bir avcıdır.","e2":"We saw a tiger at the zoo.","e2t":"Hayvanat bahçesinde bir kaplan gördük."},{"w":"till","tr":"","te":"e kadar","tt":"Preposition/Conjunction","de":"Up to the time of","dt":"... zamanına kadar","e1":"I will stay here till 5 PM.","e1t":"Saat 5'e kadar burada kalacağım.","e2":"Wait till the rain stops.","e2t":"Yağmur durana kadar bekle."},{"w":"toast","tr":"kızarmış ekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Sliced bread made brown by heat","dt":"Isıyla kahverengileşmiş dilimlenmiş ekmek","e1":"I like honey on my toast.","e1t":"Kızarmış ekmeğimde balı severim.","e2":"Let's make a toast to the bride.","e2t":"Geline kadeh kaldıralım (tost yapalım)."},{"w":"toe","tr":"ayak parmağı","te":"Noun","tt":"İsim","de":"One of the five parts at the end of the foot","dt":"Ayağın ucundaki beş parçadan biri","e1":"I hit my toe against the chair.","e1t":"Ayak parmağımı sandalyeye çarptım.","e2":"Stand on your toes.","e2t":"Parmak uçlarında dur."},{"w":"together","tr":"birlikte","te":"Adverb","tt":"Zarf","de":"With each other","dt":"Birbirleriyle","e1":"Let's go to the cinema together.","e1t":"Sinemaya birlikte gidelim.","e2":"They work well together.","e2t":"Birlikte iyi çalışıyorlar."},{"w":"toilet","tr":"tuvalet","te":"Noun","tt":"İsim","de":"A fixed bowl for body waste","dt":"Vücut atıkları için sabit kase","e1":"Where is the ladies' toilet?","e1t":"Kadınlar tuvaleti nerede?","e2":"Flush the toilet, please.","e2t":"Lütfen sifonu çek."},{"w":"tone","tr":"ton","te":"Noun","tt":"İsim","de":"The quality of a sound or voice","dt":"Bir sesin veya sesin kalitesi","e1":"Don't use that tone of voice with me.","e1t":"Benimle bu ses tonuyla konuşma.","e2":"I like the tone of this guitar.","e2t":"Bu gitarın tonunu seviyorum."},{"w":"tongue","tr":"dil","te":"Noun","tt":"İsim","de":"The organ in the mouth used for tasting","dt":"Ağızdaki tatmak için kullanılan organ","e1":"Don't stick your tongue out.","e1t":"Dilini dışarı çıkarma.","e2":"Turkish is my mother tongue.","e2t":"Türkçe benim ana dilimdir."},{"w":"tool","tr":"araç","te":"Noun","tt":"İsim","de":"A device used to perform a task","dt":"Bir görevi yerine getirmek için kullanılan cihaz","e1":"A hammer is a useful tool.","e1t":"Çekiç yararlı bir araçtır.","e2":"He has a box of tools.","e2t":"Bir alet kutusu var."},{"w":"top","tr":"üst","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The highest part or position","dt":"En yüksek parça veya konum","e1":"Put it on the top shelf.","e1t":"Onu üst rafa koy.","e2":"He reached the top of the mountain.","e2t":"Dağın zirvesine (üstüne) ulaştı."},{"w":"topic","tr":"konu","te":"Noun","tt":"İsim","de":"A subject of discussion or study","dt":"Tartışma veya çalışma konusu","e1":"What is the topic of the lesson?","e1t":"Dersin konusu nedir?","e2":"We discussed several topics.","e2t":"Birkaç konu üzerinde tartıştık."},{"w":"total","tr":"toplam","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The whole number or amount","dt":"Tüm sayı veya miktar","e1":"What is the total cost?","e1t":"Toplam maliyet nedir?","e2":"The total number of students is 30.","e2t":"Toplam öğrenci sayısı 30'dur."},{"w":"tour","tr":"tur","te":"Noun/Verb","tt":"İsim/Fiil","de":"A journey to visit several places","dt":"Birkaç yeri ziyaret etmek için yapılan yolculuk","e1":"We took a bus tour of London.","e1t":"Londra'da bir otobüs turu yaptık.","e2":"The band is on a world tour.","e2t":"Grup dünya turunda."},{"w":"tourist","tr":"turist","te":"Noun","tt":"İsim","de":"A person who travels for pleasure","dt":"Eğlence için seyahat eden kişi","e1":"The city is full of tourists in summer.","e1t":"Yazın şehir turistlerle doludur.","e2":"He is a foreign tourist.","e2t":"O yabancı bir turisttir."},{"w":"towel","tr":"havlu","te":"Noun","tt":"İsim","de":"A piece of cloth used for drying","dt":"Kurulanmak için kullanılan kumaş parçası","e1":"I need a clean towel.","e1t":"Temiz bir havluya ihtiyacım var.","e2":"Dry your hands with the towel.","e2t":"Ellerinizi havluyla kurulayın."},{"w":"tower","tr":"kule","te":"Noun","tt":"İsim","de":"A tall, narrow building","dt":"Uzun, dar bina","e1":"The Galata Tower is famous.","e1t":"Galata Kulesi ünlüdür.","e2":"Look at that high tower.","e2t":"Şu yüksek kuleye bak."},{"w":"tradition","tr":"gelenek","te":"Noun","tt":"İsim","de":"A custom or belief passed down","dt":"Nesilden nesile aktarılan gelenek veya inanç","e1":"It is a Turkish tradition.","e1t":"Bu bir Türk geleneğidir.","e2":"We follow family traditions.","e2t":"Aile geleneklerini takip ederiz."},{"w":"traditional","tr":"geleneksel","te":"Adjective","tt":"Sıfat","de":"Relating to tradition","dt":"Gelenekle ilgili olan","e1":"I like traditional Turkish music.","e1t":"Geleneksel Türk müziğini severim.","e2":"This is a traditional wedding.","e2t":"Bu geleneksel bir düğün."},{"w":"trainer","tr":"eğitmen / spor ayakkabı","te":"Noun","tt":"İsim","de":"A person who trains people or a type of shoe","dt":"İnsanları eğiten kişi veya bir ayakkabı türü","e1":"He is a fitness trainer.","e1t":"O bir fitness eğitmenidir.","e2":"I bought new trainers for running.","e2t":"Koşu için yeni spor ayakkabı (trainer) aldım."},{"w":"training","tr":"eğitim","te":"Noun","tt":"İsim","de":"The process of learning a skill","dt":"Bir beceriyi öğrenme süreci","e1":"He is doing vocational training.","e1t":"Mesleki eğitim alıyor.","e2":"The training will start at 9 AM.","e2t":"Eğitim sabah 9'da başlayacak."},{"w":"trash","tr":"çöp","te":"Noun/Verb","tt":"İsim/Fiil","de":"Waste material; garbage","dt":"Atık malzeme; çöp","e1":"Take out the trash, please.","e1t":"Lütfen çöpü dışarı çıkar.","e2":"Put it in the trash can.","e2t":"Onu çöp kutusuna koy."},{"w":"treat","tr":"tedavi etmek / davranmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give medical care or to behave toward","dt":"Tıbbi bakım vermek veya birine karşı davranmak","e1":"Doctors treat sick people.","e1t":"Doktorlar hasta insanları tedavi eder.","e2":"Treat everyone with respect.","e2t":"Herkese saygıyla davran."},{"w":"treatment","tr":"tedavi","te":"Noun","tt":"İsim","de":"Medical care or the way someone is treated","dt":"Tıbbi bakım veya birine davranılma biçimi","e1":"He is receiving medical treatment.","e1t":"Tıbbi tedavi görüyor.","e2":"The treatment was successful.","e2t":"Tedavi başarılıydı."},{"w":"trick","tr":"hile","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something done to deceive or a clever skill","dt":"Aldatmak için yapılan şey veya akıllıca bir beceri","e1":"He played a trick on me.","e1t":"Bana bir oyun (hile) oynadı.","e2":"I can show you a magic trick.","e2t":"Sana bir sihirbazlık numarası gösterebilirim."},{"w":"trouble","tr":"sorun","te":"Noun/Verb","tt":"İsim/Fiil","de":"Problems or difficulties","dt":"Sorunlar veya zorluklar","e1":"I am in trouble with my boss.","e1t":"Patronumla başım dertte (sorunum var).","e2":"Sorry to trouble you.","e2t":"Rahatsız ettiğim (sorun çıkardığım) için üzgünüm."},{"w":"trousers","tr":"pantolon","te":"Noun","tt":"İsim","de":"A piece of clothing for the lower body","dt":"Alt vücut için bir giysi parçası","e1":"I need to buy new trousers.","e1t":"Yeni bir pantolon almam gerekiyor.","e2":"These trousers are too long.","e2t":"Bu pantolon çok uzun."},{"w":"trust","tr":"güvenmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To believe that someone is honest","dt":"Birinin dürüst olduğuna inanmak","e1":"I trust my best friend.","e1t":"En iyi arkadaşıma güvenirim.","e2":"Trust is important in a relationship.","e2t":"Bir ilişkide güven önemlidir."},{"w":"truth","tr":"gerçek","te":"Noun","tt":"İsim","de":"The actual facts about something","dt":"Bir şey hakkındaki asıl gerçekler","e1":"Tell me the truth.","e1t":"Bana gerçeği söyle.","e2":"In truth, I didn't know.","e2t":"Doğrusu (gerçekte), bilmiyordum."},{"w":"tunnel","tr":"tünel","te":"Noun","tt":"İsim","de":"An underground passage","dt":"Yeraltı geçidi","e1":"The train went through a long tunnel.","e1t":"Tren uzun bir tünelden geçti.","e2":"They are building a new tunnel under the sea.","e2t":"Denizin altına yeni bir tünel inşa ediyorlar."},{"w":"turkey","tr":"hindi / Türkiye","te":"Noun","tt":"İsim","de":"A large bird or a country","dt":"Büyük bir kuş veya bir ülke","e1":"We eat turkey at Christmas.","e1t":"Noel'de hindi yeriz.","e2":"I live in Turkey.","e2t":"Türkiye'de yaşıyorum."},{"w":"turn","tr":"dönmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move in a circle or change direction","dt":"Bir daire içinde hareket etmek veya yön değiştirmek","e1":"Turn left at the corner.","e1t":"Köşeden sola dön.","e2":"It is your turn.","e2t":"Senin sıran."},{"w":"twice","tr":"iki kez","te":"Adverb","tt":"Zarf","de":"Two times","dt":"İki defa","e1":"I brush my teeth twice a day.","e1t":"Dişlerimi günde iki kez fırçalarım.","e2":"I've seen that movie twice.","e2t":"O filmi iki kez izledim."},{"w":"unable","tr":"yapamamak","te":"Adjective","tt":"Sıfat","de":"Not being able to do something","dt":"Bir şeyi yapamama durumu","e1":"He was unable to finish the work.","e1t":"İşi bitiremedi (yapamadı).","e2":"I am unable to attend the meeting.","e2t":"Toplantıya katılamıyorum."},{"w":"unclear","tr":"belirsiz","te":"Adjective","tt":"Sıfat","de":"Not easy to see, hear, or understand","dt":"Görmesi, duyması veya anlaması kolay olmayan","e1":"The instructions were unclear.","e1t":"Talimatlar belirsizdi.","e2":"His future is still unclear.","e2t":"Geleceği hâlâ belirsiz."},{"w":"uncomfortable","tr":"rahatsız","te":"Adjective","tt":"Sıfat","de":"Not feeling relaxed or physically easy","dt":"Rahatlamış veya fiziksel olarak kolay hissetmeme","e1":"These shoes are very uncomfortable.","e1t":"Bu ayakkabılar çok rahatsız.","e2":"I feel uncomfortable in this situation.","e2t":"Bu durumda kendimi rahatsız hissediyorum."},{"w":"unexpected","tr":"beklenmedik","te":"Adjective","tt":"Sıfat","de":"Not thought of as likely to happen","dt":"Olması muhtemel görülmeyen","e1":"It was an unexpected surprise.","e1t":"Beklenmedik bir sürprizdi.","e2":"The news was completely unexpected.","e2t":"Haberler tamamen beklenmedikti."},{"w":"unfair","tr":"adaletsiz","te":"Adjective","tt":"Sıfat","de":"Not treating people equally or right","dt":"İnsanlara eşit veya doğru davranmama","e1":"That is an unfair decision.","e1t":"Bu adaletsiz bir karardır.","e2":"Life is sometimes unfair.","e2t":"Hayat bazen adaletsizdir."},{"w":"unfortunately","tr":"ne yazık ki","te":"Adverb","tt":"Zarf","de":"Used to say that something is sad or bad","dt":"Bir şeyin üzücü veya kötü olduğunu söylemek için kullanılır","e1":"Unfortunately, it started to rain.","e1t":"Ne yazık ki yağmur yağmaya başladı.","e2":"I can't come, unfortunately.","e2t":"Gelemiyorum, ne yazık ki."},{"w":"unhappy","tr":"mutsuz","te":"Adjective","tt":"Sıfat","de":"Sad or not satisfied","dt":"Üzgün veya tatmin olmamış","e1":"Why are you so unhappy?","e1t":"Neden bu kadar mutsuzsun?","e2":"He was unhappy with the results.","e2t":"Sonuçlardan dolayı mutsuzdu."},{"w":"unknown","tr":"bilinmeyen","te":"Adjective","tt":"Sıfat","de":"Not known or familiar","dt":"Bilinmeyen veya tanıdık olmayan","e1":"The reason for the fire is unknown.","e1t":"Yangının sebebi bilinmiyor.","e2":"He is an unknown artist.","e2t":"O bilinmeyen bir sanatçıdır."},{"w":"unless","tr":"","te":"mezse","tt":"Conjunction","de":"Bağlaç","dt":"Except if","e1":"... olmazsa / ...","e1t":"medikçe","e2":"You will fail unless you study.","e2t":"Çalışmazsan (çalışmadığın sürece) başarısız olursun."},{"w":"until","tr":"","te":"e kadar","tt":"Preposition/Conjunction","de":"Up to a particular time","dt":"Belirli bir zamana kadar","e1":"I slept until 10 AM.","e1t":"Sabah 10'a kadar uyudum.","e2":"Wait until I come back.","e2t":"Ben geri gelene kadar bekle."},{"w":"unusual","tr":"alışılmadık","te":"Adjective","tt":"Sıfat","de":"Not common or usual","dt":"Yaygın veya olağan olmayan","e1":"It is an unusual name.","e1t":"Bu alışılmadık bir isim.","e2":"She has an unusual hobby.","e2t":"Alışılmadık bir hobisi var."},{"w":"update","tr":"güncellemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something modern or give new info","dt":"Bir şeyi modernleştirmek veya yeni bilgi vermek","e1":"You need to update your computer.","e1t":"Bilgisayarını güncellemen gerekiyor.","e2":"Here is the latest news update.","e2t":"İşte en son haber güncellemesi."},{"w":"upgrade","tr":"yükseltmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To improve something to a higher standard","dt":"Bir şeyi daha yüksek bir standarta çıkarmak","e1":"I want to upgrade my phone.","e1t":"Telefonumu yükseltmek (yeni modelini almak) istiyorum.","e2":"We got a free room upgrade at the hotel.","e2t":"Otelde ücretsiz oda yükseltmesi (daha iyi oda) aldık."},{"w":"upon","tr":"üzerinde","te":"Preposition","tt":"Edat","de":"On or immediately after","dt":"Üzerinde veya hemen sonrasında","e1":"Once upon a time...","e1t":"Bir varmış bir yokmuş... (Bir zamanlar üzerine).","e2":"Upon arrival, please call me.","e2t":"Varır varmaz (varış üzerine) lütfen beni ara."},{"w":"upper","tr":"üst","te":"Adjective","tt":"Sıfat","de":"Higher in position","dt":"Konum olarak daha yüksek","e1":"My office is on the upper floor.","e1t":"Ofisim üst kattadır.","e2":"He has an injury in his upper arm.","e2t":"Üst kolunda bir yaralanma var."},{"w":"used to","tr":"eskiden","te":"Phrase","tt":"Kalıp","de":"Done in the past but not anymore","dt":"Geçmişte yapılan ama artık yapılmayan","e1":"I used to smoke, but I quit.","e1t":"Eskiden sigara içerdim ama bıraktım.","e2":"She used to live in London.","e2t":"Eskiden Londra'da yaşardı."},{"w":"user","tr":"kullanıcı","te":"Noun","tt":"İsim","de":"A person who uses something","dt":"Bir şeyi kullanan kişi","e1":"The system has many active users.","e1t":"Sistemin birçok aktif kullanıcısı var.","e2":"Read the user manual carefully.","e2t":"Kullanıcı kılavuzunu dikkatlice oku."},{"w":"usual","tr":"alışılmış","te":"Adjective","tt":"Sıfat","de":"Normal or typical","dt":"Normal veya tipik","e1":"I'll have my usual coffee, please.","e1t":"Her zamanki (alışılmış) kahvemi alayım lütfen.","e2":"Is this the usual way?","e2t":"Alışılmış (normal) yol bu mu?"},{"w":"value","tr":"değer","te":"Noun/Verb","tt":"İsim/Fiil","de":"The importance or worth of something","dt":"Bir şeyin önemi veya ederi","e1":"What is the value of this car?","e1t":"Bu arabanın değeri nedir?","e2":"I value your friendship.","e2t":"Senin arkadaşlığına değer veriyorum."},{"w":"van","tr":"minibüs / kamyonet","te":"Noun","tt":"İsim","de":"A medium","dt":"sized vehicle for goods or people","e1":"Eşya veya insan taşıyan orta boy araç","e1t":"He drives a white delivery van.","e2":"Beyaz bir teslimat kamyoneti sürüyor.","e2t":"We rented a van for the trip."},{"w":"vegetarian","tr":"vejetaryen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who does not eat meat","dt":"Et yemeyen kişi","e1":"I am a vegetarian.","e1t":"Ben bir vejetaryenim.","e2":"Is there any vegetarian food?","e2t":"Hiç vejetaryen yemeği var mı?"},{"w":"venue","tr":"mekan","te":"Noun","tt":"İsim","de":"A place where an event happens","dt":"Bir etkinliğin gerçekleştiği yer","e1":"The concert venue was very large.","e1t":"Konser mekanı çok büyüktü.","e2":"What is the venue for the wedding?","e2t":"Düğün mekanı neresi?"},{"w":"verb","tr":"fiil","te":"Noun","tt":"İsim","de":"A word that expresses an action or state","dt":"Bir eylemi veya durumu ifade eden kelime","e1":"'Run' and 'eat' are verbs.","e1t":"'Run' (koşmak) ve 'eat' (yemek) fiillerdir.","e2":"Use the correct form of the verb.","e2t":"Fiilin doğru formunu kullanın."},{"w":"view","tr":"görüş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sight or an opinion","dt":"Bir manzara veya bir görüş","e1":"The view from the room is amazing.","e1t":"Odadan manzara harika.","e2":"In my view, it's a good plan.","e2t":"Benim görüşüme göre, bu iyi bir plan."},{"w":"visitor","tr":"ziyaretçi","te":"Noun","tt":"İsim","de":"A person who visits a place or person","dt":"Bir yeri veya kişiyi ziyaret eden kişi","e1":"The museum has many visitors today.","e1t":"Müzenin bugün birçok ziyaretçisi var.","e2":"We have a visitor from Germany.","e2t":"Almanya'dan bir ziyaretçimiz var."},{"w":"voice","tr":"ses","te":"Noun","tt":"İsim","de":"The sound made when speaking or singing","dt":"Konuşurken veya şarkı söylerken çıkan ses","e1":"She has a beautiful singing voice.","e1t":"Harika bir şarkı sesi var.","e2":"I recognized your voice.","e2t":"Sesini tanıdım."},{"w":"vote","tr":"oy vermek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To choose a leader or make a decision officially","dt":"Resmi olarak bir lider seçmek veya karar vermek","e1":"I will vote in the election tomorrow.","e1t":"Yarın seçimde oy vereceğim.","e2":"Every vote counts.","e2t":"Her oy sayılır."},{"w":"war","tr":"savaş","te":"Noun","tt":"İsim","de":"A long period of fighting between countries","dt":"Ülkeler arasındaki uzun süreli çatışma","e1":"The war lasted for five years.","e1t":"Savaş beş yıl sürdü.","e2":"We hope for an end to the war.","e2t":"Savaşın sona ermesini umuyoruz."},{"w":"warn","tr":"uyarmak","te":"Verb","tt":"Fiil","de":"To tell someone about a possible danger","dt":"Birine olası bir tehlike hakkında bilgi vermek","e1":"The sign warned about the deep water.","e1t":"Tabela derin su hakkında uyardı.","e2":"I warned him, but he didn't listen.","e2t":"Onu uyardım ama dinlemedi."},{"w":"warning","tr":"uyarı","te":"Noun","tt":"İsim","de":"Something that tells you about danger","dt":"Tehlike hakkında bilgi veren şey","e1":"Read the safety warnings carefully.","e1t":"Güvenlik uyarılarını dikkatlice oku.","e2":"This is your final warning.","e2t":"Bu senin son uyarın."},{"w":"waterfall","tr":"şelale","te":"Noun","tt":"İsim","de":"Water falling over a cliff","dt":"Bir uçurumdan düşen su","e1":"The waterfall is very high.","e1t":"Şelale çok yüksektir.","e2":"We took photos of the waterfall.","e2t":"Şelalenin fotoğraflarını çektik."},{"w":"web","tr":"ağ","te":"Noun","tt":"İsim","de":"A net made by a spider or the internet","dt":"Örümcek tarafından yapılan ağ veya internet","e1":"There is a spider web in the corner.","e1t":"Köşede bir örümcek ağı var.","e2":"Search for it on the web.","e2t":"Onu web'de (internette) ara."},{"w":"wedding","tr":"düğün","te":"Noun","tt":"İsim","de":"A ceremony where two people get married","dt":"İki kişinin evlendiği tören","e1":"We are invited to the wedding.","e1t":"Düğüne davetliyiz.","e2":"The wedding was beautiful.","e2t":"Düğün güzeldi."},{"w":"well","tr":"iyi / kuyu","te":"Adjective/Adverb/Noun","tt":"In a good way or a hole for water","de":"İyi bir şekilde veya su deliği (kuyu)","dt":"He speaks English very well.","e1":"Çok iyi İngilizce konuşuyor.","e1t":"They dug a well in the village.","e2":"Köyde bir kuyu kazdılar.","e2t":""},{"w":"whale","tr":"balina","te":"Noun","tt":"İsim","de":"A very large sea mammal","dt":"Çok büyük deniz memelisi","e1":"Whales are the largest animals on earth.","e1t":"Balinalar dünyadaki en büyük hayvanlardır.","e2":"We saw a whale in the ocean.","e2t":"Okyanusta bir balina gördük."},{"w":"while","tr":"iken","te":"Conjunction/Noun","tt":"During the time that","de":"... sırasında / ...","dt":"iken","e1":"I fell asleep while watching TV.","e1t":"TV izlerken uyuyakaldım.","e2":"Wait for a while.","e2t":"Bir süre bekle."},{"w":"whole","tr":"bütün","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Complete or all of something","dt":"Tam veya bir şeyin tamamı","e1":"I ate the whole pizza.","e1t":"Pizzanın bütününü yedim.","e2":"The whole world is watching.","e2t":"Bütün dünya izliyor."},{"w":"widely","tr":"yaygın şekilde","te":"Adverb","tt":"Zarf","de":"By many people or in many places","dt":"Birçok kişi tarafından veya birçok yerde","e1":"This book is widely read.","e1t":"Bu kitap yaygın olarak okunur.","e2":"English is widely spoken.","e2t":"İngilizce yaygın olarak konuşulur."},{"w":"wild","tr":"vahşi","te":"Adjective","tt":"Sıfat","de":"Living in nature; not controlled by humans","dt":"Doğada yaşayan; insanlarca kontrol edilmeyen","e1":"There are wild animals in the forest.","e1t":"Ormanda vahşi hayvanlar var.","e2":"He has a wild imagination.","e2t":"Vahşi (çılgın) bir hayal gücü var."},{"w":"will","tr":"niyet / irade","te":"Noun/Modal Verb","tt":"The power to decide or future marker","de":"Karar verme gücü veya gelecek zaman eki","dt":"Where there is a will, there is a way.","e1":"İrade olan yerde bir yol vardır.","e1t":"I will help you.","e2":"Sana yardım edeceğim.","e2t":""},{"w":"win","tr":"kazanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be the best in a game or competition","dt":"Bir oyunda veya yarışmada en iyisi olmak","e1":"Our team won the match.","e1t":"Takımımız maçı kazandı.","e2":"He wants to win the first prize.","e2t":"Birincilik ödülünü kazanmak istiyor."},{"w":"wine","tr":"şarap","te":"Noun","tt":"İsim","de":"An alcoholic drink made from grapes","dt":"Üzümden yapılan alkollü içecek","e1":"Red wine is famous in this region.","e1t":"Kırmızı şarap bu bölgede ünlüdür.","e2":"Do you like white wine?","e2t":"Beyaz şarap sever misin?"},{"w":"wing","tr":"kanat","te":"Noun","tt":"İsim","de":"The part of a bird or plane used for flying","dt":"Bir kuşun veya uçağın uçmak için kullanılan parçası","e1":"The bird has broken its wing.","e1t":"Kuş kanadını kırmış.","e2":"I prefer chicken wings.","e2t":"Tavuk kanadını tercih ederim."},{"w":"winner","tr":"kazanan","te":"Noun","tt":"İsim","de":"A person who wins a competition","dt":"Bir yarışmayı kazanan kişi","e1":"The winner received a trophy.","e1t":"Kazanan bir kupa aldı.","e2":"Everyone is a winner today.","e2t":"Bugün herkes kazanan."},{"w":"wire","tr":"tel","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin piece of metal","dt":"İnce metal parçası","e1":"The fence is made of wire.","e1t":"Çit telden yapılmıştır.","e2":"Don't touch the electric wires.","e2t":"Elektrik tellerine dokunma."},{"w":"wise","tr":"bilge","te":"Adjective","tt":"Sıfat","de":"Having or showing experience and knowledge","dt":"Tecrübe ve bilgiye sahip olma veya gösterme","e1":"He is a very wise old man.","e1t":"O çok bilge yaşlı bir adamdır.","e2":"That was a wise decision.","e2t":"Bu bilgece (mantıklı) bir karardı."},{"w":"wish","tr":"dilemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To want something that is not possible","dt":"Mümkün olmayan bir şeyi istemek","e1":"I wish I could fly.","e1t":"Keşke uçabilsem (uçmayı dilerdim).","e2":"Make a wish!","e2t":"Bir dilek tut!"},{"w":"wonderful","tr":"harika","te":"Adjective","tt":"Sıfat","de":"Extremely good; marvelous","dt":"Son derece iyi; harika","e1":"We had a wonderful time.","e1t":"Harika vakit geçirdik.","e2":"The weather is wonderful today.","e2t":"Bugün hava harika."},{"w":"wood","tr":"ahşap","te":"Noun","tt":"İsim","de":"The material that trees are made of","dt":"Ağaçların yapıldığı malzeme","e1":"The table is made of solid wood.","e1t":"Masa masif ahşaptan yapılmıştır.","e2":"We need more wood for the fire.","e2t":"Ateş için daha fazla oduna ihtiyacımız var."},{"w":"worry","tr":"endişelenmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel anxious or troubled","dt":"Endişeli veya sıkıntılı hissetmek","e1":"Don't worry about the exam.","e1t":"Sınav için endişelenme.","e2":"My main worry is the cost.","e2t":"Temel endişem maliyettir."},{"w":"would","tr":"","te":"erdi","tt":"Modal Verb","de":"Used for imagined situations or past habits","dt":"Hayali durumlar veya geçmişteki alışkanlıklar için","e1":"I would love to go to Paris.","e1t":"Paris'e gitmeyi çok isterdim.","e2":"He would always bring me flowers.","e2t":"Bana her zaman çiçek getirirdi."},{"w":"writer","tr":"yazar","te":"Noun","tt":"İsim","de":"A person who writes books or articles","dt":"Kitap veya makale yazan kişi","e1":"He is a famous travel writer.","e1t":"O ünlü bir seyahat yazarıdır.","e2":"She wants to be a professional writer.","e2t":"Profesyonel bir yazar olmak istiyor."},{"w":"writing","tr":"yazı","te":"Noun","tt":"İsim","de":"The activity of using pen and paper","dt":"Kağıt ve kalem kullanma aktivitesi","e1":"Your writing is difficult to read.","e1t":"Yazını okumak zor.","e2":"He is busy with his writing.","e2t":"Yazısıyla meşgul."},{"w":"youth","tr":"gençlik","te":"Noun","tt":"İsim","de":"The period between childhood and adult age","dt":"Çocukluk ve yetişkinlik arasındaki dönem","e1":"He spent his youth in London.","e1t":"Gençliğini Londra'da geçirdi.","e2":"The youth of today love technology.","e2t":"Günümüz gençliği teknolojiyi seviyor."},{"w":"b1","tr":"","te":"","tt":"","de":"","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"abandon","tr":"terk etmek","te":"Verb","tt":"Fiil","de":"To leave a place, thing, or person forever","dt":"Bir yeri, şeyi veya kişiyi sonsuza dek bırakmak","e1":"They had to abandon the car in the snow.","e1t":"Arabayı karda terk etmek zorunda kaldılar.","e2":"The match was abandoned due to rain.","e2t":"Maç yağmur nedeniyle iptal edildi (bırakıldı)."},{"w":"absolute","tr":"kesin / mutlak","te":"Adjective","tt":"Sıfat","de":"Very great or to the largest degree possible","dt":"Çok büyük veya mümkün olan en yüksek derecede","e1":"I have absolute confidence in her.","e1t":"Ona güvenim tam (mutlak).","e2":"That is the absolute truth.","e2t":"Bu kesin gerçektir."},{"w":"absorb","tr":"emmek / soğurmak","te":"Verb","tt":"Fiil","de":"To take in a liquid, gas or other substance","dt":"Bir sıvıyı, gazı veya başka bir maddeyi içine almak","e1":"Plants absorb carbon dioxide.","e1t":"Bitkiler karbondioksiti emer.","e2":"This paper towel absorbs water quickly.","e2t":"Bu kağıt havlu suyu hızlıca emer."},{"w":"abstract","tr":"soyut","te":"Adjective","tt":"Sıfat","de":"Existing as an idea but not as a physical object","dt":"Fikir olarak var olan ancak fiziksel bir nesne olmayan","e1":"Truth and love are abstract concepts.","e1t":"Gerçek ve sevgi soyut kavramlardır.","e2":"I don't like abstract art.","e2t":"Soyut sanatı sevmem."},{"w":"abuse","tr":"kötüye kullanmak / istismar","te":"Verb/Noun","tt":"Fiil/İsim","de":"To use something for the wrong purpose","dt":"Bir şeyi yanlış amaçla kullanmak","e1":"He abused his power as a manager.","e1t":"Müdür olarak yetkisini kötüye kullandı.","e2":"Drug abuse is a serious problem.","e2t":"Uyuşturucu bağımlılığı (kötüye kullanımı) ciddi bir sorundur."},{"w":"academic","tr":"akademik","te":"Adjective","tt":"Sıfat","de":"Relating to schools, colleges, and universities","dt":"Okullar, kolejler ve üniversitelerle ilgili","e1":"She has a strong academic background.","e1t":"Güçlü bir akademik geçmişi var.","e2":"Academic standards are high in this school.","e2t":"Bu okulda akademik standartlar yüksektir."},{"w":"acceptable","tr":"kabul edilebilir","te":"Adjective","tt":"Sıfat","de":"Satisfactory and able to be agreed to","dt":"Tatmin edici ve üzerinde anlaşılabilir","e1":"This behavior is not acceptable.","e1t":"Bu davranış kabul edilebilir değil.","e2":"We need to find an acceptable solution.","e2t":"Kabul edilebilir bir çözüm bulmalıyız."},{"w":"accessible","tr":"erişilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be reached or easily understood","dt":"Ulaşılabilir veya kolayca anlaşılabilir","e1":"The building is accessible for wheelchairs.","e1t":"Bina tekerlekli sandalyeler için erişilebilirdir.","e2":"Information is more accessible now with the internet.","e2t":"İnternet ile bilgi artık daha erişilebilir."},{"w":"accompany","tr":"eşlik etmek","te":"Verb","tt":"Fiil","de":"To go with someone or to exist at the same time","dt":"Biriyle gitmek veya aynı anda var olmak","e1":"Children must be accompanied by an adult.","e1t":"Çocuklara bir yetişkin eşlik etmelidir.","e2":"I will accompany you to the station.","e2t":"Sana istasyona kadar eşlik edeceğim."},{"w":"accomplish","tr":"başarmak","te":"Verb","tt":"Fiil","de":"To finish something successfully","dt":"Bir şeyi başarıyla tamamlamak","e1":"We can accomplish anything if we work together.","e1t":"Birlikte çalışırsak her şeyi başarabiliriz.","e2":"He finally accomplished his mission.","e2t":"Sonunda görevini başardı."},{"w":"account","tr":"hesap / açıklama / açıklamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A report of an event or money in a bank","dt":"Bir olayın raporu veya bankadaki para","e1":"I need to open a bank account.","e1t":"Bir banka hesabı açmam gerekiyor.","e2":"Can you account for your absence?","e2t":"Devamsızlığınızı açıklayabilir misiniz?"},{"w":"accuracy","tr":"doğruluk / kesinlik","te":"Noun","tt":"İsim","de":"The state of being correct or exact","dt":"Doğru veya kesin olma durumu","e1":"I doubt the accuracy of this report.","e1t":"Bu raporun doğruluğundan şüphe ediyorum.","e2":"Accuracy is very important in science.","e2t":"Bilimde kesinlik çok önemlidir."},{"w":"accurate","tr":"doğru / hatasız","te":"Adjective","tt":"Sıfat","de":"Correct, exact, and without any mistakes","dt":"Doğru, kesin ve hatasız","e1":"This map is not very accurate.","e1t":"Bu harita pek doğru değil.","e2":"We need accurate information before we decide.","e2t":"Karar vermeden önce doğru bilgiye ihtiyacımız var."},{"w":"accuse","tr":"suçlamak","te":"Verb","tt":"Fiil","de":"To say that someone has done something wrong","dt":"Birinin yanlış bir şey yaptığını söylemek","e1":"He was accused of stealing the car.","e1t":"Araba çalmakla suçlandı.","e2":"Don't accuse me without evidence.","e2t":"Kanıt olmadan beni suçlama."},{"w":"acknowledge","tr":"kabul etmek / onaylamak","te":"Verb","tt":"Fiil","de":"To accept that something is true or exists","dt":"Bir şeyin doğru olduğunu veya varlığını kabul etmek","e1":"He acknowledged his mistake.","e1t":"Hatasını kabul etti.","e2":"Please acknowledge receipt of this email.","e2t":"Lütfen bu e"},{"w":"acquire","tr":"edinmek / kazanmak","te":"Verb","tt":"Fiil","de":"To get something, usually by buying or learning","dt":"Genellikle satın alarak veya öğrenerek bir şey elde etmek","e1":"He acquired a new company.","e1t":"Yeni bir şirket satın aldı (edindi).","e2":"She acquired a lot of knowledge in college.","e2t":"Üniversitede çok fazla bilgi edindi."},{"w":"activate","tr":"etkinleştirmek","te":"Verb","tt":"Fiil","de":"To make something start working","dt":"Bir şeyin çalışmaya başlamasını sağlamak","e1":"You need to activate your card.","e1t":"Kartınızı etkinleştirmeniz gerekiyor.","e2":"Smoke activated the fire alarm.","e2t":"Duman yangın alarmını etkinleştirdi."},{"w":"actual","tr":"gerçek / asıl","te":"Adjective","tt":"Sıfat","de":"Real and not imagined","dt":"Gerçek olan ve hayali olmayan","e1":"The actual cost was higher than we expected.","e1t":"Asıl maliyet beklediğimizden daha yüksekti.","e2":"What was his actual words?","e2t":"Onun asıl sözleri neydi?"},{"w":"adapt","tr":"uyum sağlamak / uyarlamak","te":"Verb","tt":"Fiil","de":"To change to suit different conditions","dt":"Farklı koşullara uymak için değişmek","e1":"It's hard to adapt to a new climate.","e1t":"Yeni bir iklime uyum sağlamak zordur.","e2":"The movie was adapted from a book.","e2t":"Film bir kitaptan uyarlandı."},{"w":"adequate","tr":"yeterli","te":"Adjective","tt":"Sıfat","de":"Enough or satisfactory for a particular purpose","dt":"Belirli bir amaç için yeterli veya tatmin edici","e1":"The room is small but adequate.","e1t":"Oda küçük ama yeterli.","e2":"We didn't have adequate time to prepare.","e2t":"Hazırlanmak için yeterli vaktimiz yoktu."},{"w":"adjust","tr":"ayarlamak","te":"Verb","tt":"Fiil","de":"To change something slightly to make it correct","dt":"Bir şeyi doğru hale getirmek için hafifçe değiştirmek","e1":"You can adjust the seat to your height.","e1t":"Koltuğu boyunuza göre ayarlayabilirsiniz.","e2":"It took me time to adjust to my new job.","e2t":"Yeni işime alışmam (ayarlanmam) zaman aldı."},{"w":"administration","tr":"yönetim / idare","te":"Noun","tt":"İsim","de":"The process of managing a company or org","dt":"Bir şirketi veya organizasyonu yönetme süreci","e1":"He works in the hospital administration.","e1t":"Hastane yönetiminde çalışıyor.","e2":"The new administration started last month.","e2t":"Yeni yönetim geçen ay başladı."},{"w":"advanced","tr":"ileri düzey","te":"Adjective","tt":"Sıfat","de":"At a higher, more difficult level","dt":"Daha yüksek, daha zor bir seviyede","e1":"She is an advanced student of English.","e1t":"O, ileri düzey bir İngilizce öğrencisidir.","e2":"We are using advanced technology.","e2t":"İleri teknoloji kullanıyoruz."},{"w":"advantage","tr":"avantaj / yarar","te":"Noun","tt":"İsim","de":"A condition that helps you to be successful","dt":"Başarılı olmanıza yardımcı olan bir durum","e1":"One advantage of living here is the low cost.","e1t":"Burada yaşamanın bir avantajı düşük maliyettir.","e2":"He took advantage of the opportunity.","e2t":"Fırsattan yararlandı (avantaj sağladı)."},{"w":"adventure","tr":"macera","te":"Noun","tt":"İsim","de":"An exciting and sometimes dangerous experience","dt":"Heyecan verici ve bazen tehlikeli olan deneyim","e1":"We went on a mountain adventure.","e1t":"Bir dağ macerasına çıktık.","e2":"Life is a great adventure.","e2t":"Hayat büyük bir maceradır."},{"w":"advocate","tr":"savunmak / desteklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To publicly support a policy or way of doing things","dt":"Bir politikayı veya iş yapış biçimini kamuya açıkça desteklemek","e1":"He advocates for children's rights.","e1t":"Çocuk haklarını savunuyor.","e2":"She is a strong advocate of organic farming.","e2t":"O, organik tarımın güçlü bir savunucusudur."},{"w":"airline","tr":"hava yolu şirketi","te":"Noun","tt":"İsim","de":"A company that provides regular flights for passengers","dt":"Yolcular için düzenli uçuşlar sağlayan şirket","e1":"Which airline are you flying with?","e1t":"Hangi hava yolu şirketiyle uçuyorsun?","e2":"The airline canceled our flight.","e2t":"Hava yolu şirketi uçuşumuzu iptal etti."},{"w":"aisle","tr":"koridor (koltuk arası)","te":"Noun","tt":"İsim","de":"A long, narrow space between rows of seats","dt":"Koltuk sıraları arasındaki uzun, dar boşluk","e1":"Would you like a window or an aisle seat?","e1t":"Pencere kenarı mı yoksa koridor koltuğu mu istersiniz?","e2":"He walked down the aisle to find his seat.","e2t":"Koltuğunu bulmak için koridorda yürüdü."},{"w":"alert","tr":"uyanık / tetikte / uyarı","te":"Adjective/Noun/Verb","tt":"Quick to notice things or a warning","de":"Şeyleri fark etmede hızlı olma veya bir uyarı","dt":"You must stay alert while driving.","e1":"Araba sürerken tetikte (dikkatli) kalmalısın.","e1t":"The red light is an alert.","e2":"Kırmızı ışık bir uyarıdır.","e2t":""},{"w":"alien","tr":"yabancı / uzaylı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A creature from another planet or a foreigner","dt":"Başka bir gezegenden gelen yaratık veya yabancı","e1":"Do you believe in aliens?","e1t":"Uzaylılara inanır mısın?","e2":"He felt like an alien in the new city.","e2t":"Yeni şehirde bir yabancı gibi hissetti."},{"w":"alike","tr":"benzer / farksız","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Similar to each other","dt":"Birbirine benzer","e1":"The two brothers are very much alike.","e1t":"İki kardeş birbirine çok benzer.","e2":"Friends and family alike were invited.","e2t":"Arkadaşlar ve aile farksız (aynı şekilde) davet edildi."},{"w":"alternative","tr":"seçenek / alternatif","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"One of two or more things that you can choose","dt":"Seçebileceğiniz iki veya daha fazla şeyden biri","e1":"We have no other alternative.","e1t":"Başka bir alternatifimiz (seçeneğimiz) yok.","e2":"Is there an alternative way to solve this?","e2t":"Bunu çözmek için alternatif bir yol var mı?"},{"w":"altogether","tr":"tamamen / büsbütün","te":"Adverb","tt":"Zarf","de":"Completely; totally","dt":"Tam anlamıyla, bütünüyle","e1":"I am not altogether sure about this.","e1t":"Bu konuda tamamen emin değilim.","e2":"Stop altogether.","e2t":"Tamamen durmak."},{"w":"amaze","tr":"şaşırtmak","te":"Verb","tt":"Fiil","de":"To fill someone with great surprise","dt":"Birini çok şaşırtmak","e1":"Your progress amazes me.","e1t":"İlerlemen beni şaşırtıyor.","e2":"It amazes me that...","e2t":"... beni hayretler içinde bırakıyor."},{"w":"ambitious","tr":"hırslı / azimli","te":"Adjective","tt":"Sıfat","de":"Having a strong desire to succeed","dt":"Başarılı olmak için güçlü bir istek duyan","e1":"He is a very ambitious young lawyer.","e1t":"O çok azimli genç bir avukat.","e2":"Ambitious plan.","e2t":"İddialı (hırslı) plan."},{"w":"amuse","tr":"eğlendirmek / güldürmek","te":"Verb","tt":"Fiil","de":"To make someone laugh or smile","dt":"Birini güldürmek veya eğlendirmek","e1":"The clown amused the children.","e1t":"Palyaço çocukları eğlendirdi.","e2":"Amuse oneself.","e2t":"Kendi kendine eğlenmek."},{"w":"ancestor","tr":"ata / ced","te":"Noun","tt":"İsim","de":"A person related to you who lived a long time ago","dt":"Çok uzun zaman önce yaşamış olan akrabanız","e1":"My ancestors came from Central Asia.","e1t":"Atalarım Orta Asya'dan gelmiş.","e2":"We should respect our ancestors.","e2t":"Atalarımıza saygı duymalıyız."},{"w":"annoy","tr":"rahatsız etmek / kızdırmak","te":"Verb","tt":"Fiil","de":"To make someone feel slightly angry","dt":"Birini hafifçe kızdırmak","e1":"Please stop making that noise, it annoys me.","e1t":"Lütfen o gürültüyü yapmayı kes, beni rahatsız ediyor.","e2":"His behavior annoyed everyone.","e2t":"Onun davranışı herkesi kızdırdı."},{"w":"anyhow","tr":"her neyse / her halükarda","te":"Adverb","tt":"Zarf","de":"Anyway; in any case","dt":"Her durumda, nasıl olsa","e1":"It's too late now, anyhow.","e1t":"Her halükarda artık çok geç.","e2":"Anyhow, as I was saying...","e2t":"Neyse, diyordum ki..."},{"w":"apparent","tr":"belirgin / aşikar","te":"Adjective","tt":"Sıfat","de":"Able to be seen or understood easily","dt":"Kolayca görülebilen veya anlaşılabilen","e1":"It was apparent that he was lying.","e1t":"Yalan söylediği aşikardı.","e2":"The reason for his success is apparent.","e2t":"Başarısının nedeni belirgindir."},{"w":"applicant","tr":"başvuran (kişi)","te":"Noun","tt":"İsim","de":"A person who formally requests something (job/place)","dt":"Bir şeyi (iş/yer) resmi olarak talep eden kişi","e1":"There were over 100 applicants for the job.","e1t":"İş için 100'den fazla başvuran vardı.","e2":"The successful applicant will start next week.","e2t":"Başarılı aday (başvuran) haftaya başlayacak."},{"w":"application","tr":"başvuru / uygulama / aplikasyon","te":"Noun","tt":"İsim","de":"A formal request or a computer program","dt":"Resmi bir talep veya bilgisayar programı","e1":"I sent my job application yesterday.","e1t":"İş başvurumu dün gönderdim.","e2":"This application works on mobile phones.","e2t":"Bu uygulama (aplikasyon) cep telefonlarında çalışır."},{"w":"appointment","tr":"randevu / atama","te":"Noun","tt":"İsim","de":"A formal arrangement to meet","dt":"Buluşmak için yapılan resmi anlaşma","e1":"I have a dentist appointment at 3.","e1t":"Saat 3'te dişçi randevum var.","e2":"Make an appointment.","e2t":"Randevu almak."},{"w":"appreciate","tr":"takdir etmek / değerini bilmek","te":"Verb","tt":"Fiil","de":"To recognize the full worth of something","dt":"Bir şeyin değerini anlamak","e1":"I really appreciate your help.","e1t":"Yardımını gerçekten takdir ediyorum.","e2":"Highly appreciate.","e2t":"Çok takdir etmek."},{"w":"approach","tr":"yaklaşmak / yaklaşım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come near or a way of dealing with something","dt":"Yakına gelmek veya bir şeyle ilgilenme yolu","e1":"The plane is approaching the runway.","e1t":"Uçak piste yaklaşıyor.","e2":"I like your approach to the problem.","e2t":"Soruna olan yaklaşımını seviyorum."},{"w":"appropriate","tr":"uygun / yerinde","te":"Adjective","tt":"Sıfat","de":"Suitable or right for a particular situation","dt":"Belirli bir durum için uygun veya doğru","e1":"Is this dress appropriate for a wedding?","e1t":"Bu elbise bir düğün için uygun mu?","e2":"Use appropriate language in the office.","e2t":"Ofiste uygun bir dil kullanın."},{"w":"approval","tr":"onay","te":"Noun","tt":"İsim","de":"The feeling that something is good or acceptable","dt":"Bir şeyin iyi veya kabul edilebilir olduğu hissi","e1":"I need my manager's approval to buy this.","e1t":"Bunu satın almak için müdürümün onayına ihtiyacım var.","e2":"The plan won official approval.","e2t":"Plan resmi onay aldı."},{"w":"approximate","tr":"yaklaşık","te":"Adjective/Verb","tt":"Close to the actual, but not exact","de":"Gerçeğe yakın ama kesin olmayan","dt":"The approximate cost is 100 dollars.","e1":"Yaklaşık maliyet 100 dolar.","e1t":"Approximate time.","e2":"Tahmini süre.","e2t":""},{"w":"arms","tr":"silahlar","te":"Noun","tt":"İsim","de":"Weapons and equipment used in war","dt":"Savaşta kullanılan silahlar ve ekipmanlar","e1":"The government is buying new arms.","e1t":"Hükümet yeni silahlar alıyor.","e2":"They were carrying arms.","e2t":"Silah taşıyorlardı."},{"w":"aspect","tr":"yön / özellik / bakış","te":"Noun","tt":"İsim","de":"One part of a situation, problem, or subject","dt":"Bir durumun, sorunun veya konunun bir parçası","e1":"Which aspect of the job do you like most?","e1t":"İşin en çok hangi yönünü seviyorsun?","e2":"We must consider every aspect of the plan.","e2t":"Planın her yönünü değerlendirmeliyiz."},{"w":"assess","tr":"değerlendirmek / değer biçmek","te":"Verb","tt":"Fiil","de":"To judge or decide the amount or value of something","dt":"Bir şeyin miktarını veya değerini yargılamak/belirlemek","e1":"We need to assess the risks.","e1t":"Riskleri değerlendirmeliyiz.","e2":"Experts assessed the value of the house.","e2t":"Uzmanlar evin değerini belirledi (değer biçti)."},{"w":"assessment","tr":"değerlendirme","te":"Noun","tt":"İsim","de":"The act of judging or deciding the value","dt":"Değeri yargılama veya belirleme eylemi","e1":"The teacher's assessment was fair.","e1t":"Öğretmenin değerlendirmesi adildi.","e2":"We need a needs assessment for the project.","e2t":"Proje için bir ihtiyaç değerlendirmesine ihtiyacımız var."},{"w":"asset","tr":"varlık / değerli şey","te":"Noun","tt":"İsim","de":"A useful or valuable quality, skill, or person","dt":"Yararlı veya değerli özellik, beceri veya kişi","e1":"Knowledge of English is a great asset.","e1t":"İngilizce bilgisi büyük bir varlıktır (değerdir).","e2":"The company's assets include buildings and land.","e2t":"Şirketin varlıkları binaları ve arazileri içerir."},{"w":"assign","tr":"atamak / görevlendirmek","te":"Verb","tt":"Fiil","de":"To give someone a particular job or task","dt":"Birine belirli bir iş veya görev vermek","e1":"The teacher assigned homework to the class.","e1t":"Öğretmen sınıfa ödev verdi (atadı).","e2":"They assigned a new manager to the branch.","e2t":"Şubeye yeni bir müdür atadılar."},{"w":"assure","tr":"garanti etmek / temin etmek","te":"Verb","tt":"Fiil","de":"To tell someone that something is definitely true","dt":"Birine bir şeyin kesinlikle doğru olduğunu söylemek","e1":"I assure you that everything will be fine.","e1t":"Sana temin ederim ki (garanti ederim ki) her şey iyi olacak.","e2":"He assured me of his support.","e2t":"Bana desteği konusunda güvence verdi."},{"w":"astonishing","tr":"şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Very surprising","dt":"Çok şaşırtıcı","e1":"It was an astonishing achievement.","e1t":"Şaşırtıcı bir başarıydı.","e2":"The view from the top was astonishing.","e2t":"Tepeden manzara şaşırtıcıydı."},{"w":"attendance","tr":"katılım / devam","te":"Noun","tt":"İsim","de":"The act of being present at a place","dt":"Bir yerde mevcut bulunma eylemi","e1":"Attendance at school is compulsory.","e1t":"Okula devam (katılım) zorunludur.","e2":"We had a record attendance at the meeting.","e2t":"Toplantıda rekor bir katılım sağladık."},{"w":"attorney","tr":"avukat / vekil","te":"Noun","tt":"İsim","de":"A person, especially a lawyer, who can act for another","dt":"Bir başkasının adına hareket edebilen kişi, özellikle avukat","e1":"He hired an attorney to defend him.","e1t":"Kendini savunması için bir avukat tuttu.","e2":"She has a power of attorney for her father.","e2t":"Babası için vekaletnameye (vekillik yetkisine) sahip."},{"w":"attraction","tr":"çekicilik / cazibe / ilgi odağı","te":"Noun","tt":"İsim","de":"Something that makes people want to go to a place","dt":"İnsanların bir yere gitmesini sağlayan şey","e1":"The Blue Mosque is a major tourist attraction.","e1t":"Sultanahmet Camii önemli bir turistik ilgi odağıdır.","e2":"I don't see the attraction of living in a cold city.","e2t":"Soğuk bir şehirde yaşamanın cazibesini göremiyorum."},{"w":"authority","tr":"otorite / yetki","te":"Noun","tt":"İsim","de":"The moral or legal right or ability to control","dt":"Kontrol etme konusundaki ahlaki veya yasal hak veya yetenek","e1":"He has no authority over me.","e1t":"Benim üzerimde hiçbir yetkisi yok.","e2":"The local authorities are investigating the case.","e2t":"Yerel makamlar (otoriteler) olayı araştırıyor."},{"w":"awareness","tr":"farkındalık","te":"Noun","tt":"İsim","de":"Knowledge that something exists","dt":"Bir şeyin var olduğuna dair bilgi","e1":"We need to raise environmental awareness.","e1t":"Çevresel farkındalığı artırmalıyız.","e2":"There is a growing awareness of the problem.","e2t":"Soruna dair büyüyen bir farkındalık var."},{"w":"awkward","tr":"garip / sakar / kullanışsız","te":"Adjective","tt":"Sıfat","de":"Difficult to use, do, or deal with; embarrassing","dt":"Kullanması, yapması veya başa çıkması zor; utandırıcı","e1":"There was an awkward silence in the room.","e1t":"Odada garip (huzursuz edici) bir sessizlik vardı.","e2":"This tool is very awkward to use.","e2t":"Bu aleti kullanmak çok kullanışsız."},{"w":"baggage","tr":"bagaj","te":"Noun","tt":"İsim","de":"Cases and bags used for carrying belongings","dt":"Eşya taşımak için kullanılan valiz ve çantalar","e1":"How many pieces of baggage do you have?","e1t":"Kaç parça bagajınız var?","e2":"Excess baggage.","e2t":"Fazla bagaj."},{"w":"bake","tr":"fırında pişirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cook food using dry heat in an oven","dt":"Fırında kuru ısı ile yemek pişirmek","e1":"I like to bake fresh bread.","e1t":"Taze ekmek pişirmeyi severim.","e2":"Baked potato.","e2t":"Fırınlanmış patates."},{"w":"bakery","tr":"fırın (dükkan)","te":"Noun","tt":"İsim","de":"A place where bread and cakes are made or sold","dt":"Ekmek ve keklerin yapıldığı veya satıldığı yer","e1":"I bought some fresh rolls at the bakery.","e1t":"Fırından taze sandviç ekmeği aldım.","e2":"Local bakery.","e2t":"Mahalle fırını."},{"w":"banish","tr":"sürgün etmek / kafasından atmak","te":"Verb","tt":"Fiil","de":"To send someone away from a country; or to get rid of a thought","dt":"Birini ülkeden uzaklaştırmak; veya bir düşünceden kurtulmak","e1":"He was banished from the kingdom.","e1t":"Krallıktan sürgün edildi.","e2":"Banish fear.","e2t":"Korkuyu kafasından atmak."},{"w":"banker","tr":"bankacı","te":"Noun","tt":"İsim","de":"A person who manages or owns a bank","dt":"Bir bankayı yöneten veya sahibi olan kişi","e1":"Her father is a successful investment banker.","e1t":"Babası başarılı bir yatırım bankacısıdır.","e2":"Personal banker.","e2t":"Bireysel müşteri temsilcisi."},{"w":"basement","tr":"bodrum katı","te":"Noun","tt":"İsim","de":"The floor of a building which is partly or entirely below ground level","dt":"Binanın kısmen veya tamamen yer altında kalan katı","e1":"We store old things in the basement.","e1t":"Eski şeyleri bodrumda saklıyoruz.","e2":"Basement flat.","e2t":"Bodrum kat daire."},{"w":"basically","tr":"esasen / temelde","te":"Adverb","tt":"Zarf","de":"Simply; in the most important ways","dt":"Basitçe; en önemli yönleriyle","e1":"The two plans are basically the same.","e1t":"İki plan esasen aynıdır.","e2":"Basically, we need more time.","e2t":"Temelde, daha fazla zamana ihtiyacımız var."},{"w":"basin","tr":"havza / leğen / lavabo","te":"Noun","tt":"İsim","de":"A large bowl for water; or an area of land","dt":"Su için büyük kase; veya bir arazi bölgesi","e1":"Put the dirty dishes in the basin.","e1t":"Kirli bulaşıkları leğene koy.","e2":"River basin.","e2t":"Nehir havzası."},{"w":"basket","tr":"sepet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A container made of woven material","dt":"Örme malzemeden yapılmış kap","e1":"A picnic basket.","e1t":"Piknik sepeti.","e2":"Shopping basket.","e2t":"Alışveriş sepeti."},{"w":"bath","tr":"banyo / yıkanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The act of washing your whole body","dt":"Tüm vücudu yıkama eylemi","e1":"I’m going to take a hot bath.","e1t":"Sıcak bir banyo yapacağım.","e2":"Bubble bath.","e2t":"Köpük banyosu."},{"w":"beam","tr":"kiriş / ışın / gülümsemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long piece of wood or metal; or a ray of light","dt":"Uzun tahta veya metal parça; veya ışık hüzmesi","e1":"A laser beam.","e1t":"Lazer ışını.","e2":"He beamed with joy.","e2t":"Sevinçle gülümsedi."},{"w":"beer","tr":"bira","te":"Noun","tt":"İsim","de":"An alcoholic drink made from grain","dt":"Tahıldan yapılan alkollü içecek","e1":"A bottle of beer.","e1t":"Bir şişe bira.","e2":"Cold beer.","e2t":"Soğuk bira."},{"w":"beforehand","tr":"önceden / vaktinden evvel","te":"Adverb","tt":"Zarf","de":"Earlier; in advance","dt":"Daha önce; peşinen","e1":"I wish I had known beforehand.","e1t":"Keşke önceden bilseydim.","e2":"Plan beforehand.","e2t":"Önceden planlamak."},{"w":"behalf","tr":"adına / namına","te":"Noun","tt":"İsim","de":"Representing someone else","dt":"Bir başkasını temsil etme","e1":"I am calling on behalf of my manager.","e1t":"Müdürüm adına arıyorum.","e2":"He accepted the award on behalf of the team.","e2t":"Ödülü takım adına kabul etti."},{"w":"believable","tr":"inanılır","te":"Adjective","tt":"Sıfat","de":"Able to be believed","dt":"İnanılabilir olan","e1":"Her story was not very believable.","e1t":"Onun hikayesi pek inanılır değildi.","e2":"He is a believable character in the movie.","e2t":"Filmde inanılır (ikna edici) bir karakter."},{"w":"beside","tr":"yanında","te":"Preposition","tt":"Edat","de":"At the side of; next to","dt":"Yan tarafında; bitişiğinde","e1":"Sit beside me.","e1t":"Yanıma otur.","e2":"Beside the river.","e2t":"Nehir yanında."},{"w":"best","tr":"en iyi","te":"Adjective/Adverb/Noun/Verb","tt":"Of the highest quality","de":"En yüksek kalitede olan","dt":"He is my best friend.","e1":"O benim en iyi arkadaşım.","e1t":"Do your best.","e2":"Elinden gelenin en iyisini yap.","e2t":""},{"w":"bet","tr":"bahis / iddiaya girmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To risk money on a result","dt":"Bir sonuç üzerine para riske atmak","e1":"I bet you can't do it.","e1t":"Yapamayacağına iddiaya girerim.","e2":"Win a bet.","e2t":"Bahis kazanmak."},{"w":"bias","tr":"önyargı / taraflılık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A personal preference or prejudice","dt":"Kişisel tercih veya önyargı","e1":"The news report showed a strong bias.","e1t":"Haber raporu güçlü bir taraflılık (önyargı) gösterdi.","e2":"He is biased against young workers.","e2t":"Genç işçilere karşı önyargılıdır."},{"w":"bicycle","tr":"bisiklet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle with two wheels","dt":"İki tekerlekli araç","e1":"I go to school by bicycle.","e1t":"Okula bisikletle giderim.","e2":"Ride a bicycle.","e2t":"Bisiklet sürmek."},{"w":"bid","tr":"teklif / teklif vermek","te":"Verb/Noun","tt":"Fiil/İsim","de":"An offer of a price","dt":"Fiyat teklifi","e1":"He bid 50 dollars for the vase.","e1t":"Vazo için 50 dolar teklif verdi.","e2":"Make a bid.","e2t":"Teklif yapmak."},{"w":"bind","tr":"bağlamak / ciltlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To tie or fasten tightly","dt":"Sıkıca bağlamak veya tutturmak","e1":"Bind the sticks together.","e1t":"Çubukları birbirine bağla.","e2":"Bind a book.","e2t":"Kitap ciltlemek."},{"w":"birthplace","tr":"doğum yeri","te":"Noun","tt":"İsim","de":"The place where a person was born","dt":"Bir kişinin doğduğu yer","e1":"Stratford is the birthplace of Shakespeare.","e1t":"Stratford, Shakespeare'in doğum yeridir.","e2":"Record your birthplace.","e2t":"Doğum yerini kaydetmek."},{"w":"biscuit","tr":"bisküvi / kurabiye","te":"Noun","tt":"İsim","de":"A small, flat, crisp cake, usually sweet","dt":"Küçük, yassı, gevrek ve genellikle tatlı çörek","e1":"Would you like a chocolate biscuit?","e1t":"Çikolatalı bir bisküvi ister misin?","e2":"A packet of biscuits.","e2t":"Bir paket bisküvi."},{"w":"bishop","tr":"piskopos","te":"Noun","tt":"İsim","de":"A senior member of the Christian clergy","dt":"Hristiyan din görevlilerinin kıdemli bir üyesi","e1":"The bishop visited the local church.","e1t":"Piskopos yerel kiliseyi ziyaret etti.","e2":"Chess bishop.","e2t":"Satrançtaki fil taşı."},{"w":"bitter","tr":"acı (tat) / sert / kırgın","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having a sharp, pungent taste; or feeling resentful","dt":"Keskin, yakıcı bir tada sahip; veya içerlemiş","e1":"This coffee has a very bitter taste.","e1t":"Bu kahvenin çok acı bir tadı var.","e2":"Bitter enemy.","e2t":"Ezeli düşman."},{"w":"blackmail","tr":"şantaj / şantaj yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The action of demanding money in exchange for not revealing a secret","dt":"Bir sırrı açıklamama karşılığında para talep etme eylemi","e1":"He was accused of blackmail.","e1t":"Şantajla suçlandı.","e2":"Emotional blackmail.","e2t":"Duygusal şantaj."},{"w":"blast","tr":"patlama / şiddetli rüzgar / patlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A destructive wave of air from an explosion; or a loud noise","dt":"Patlamadan kaynaklanan hava dalgası; veya yüksek ses","e1":"The blast broke all the windows.","e1t":"Patlama tüm camları kırdı.","e2":"Blast off.","e2t":"(Roket için) havalanmak."},{"w":"blaze","tr":"alev / parlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very large or fiercely burning fire","dt":"Çok büyük veya şiddetli yanan ateş","e1":"Firefighters fought the blaze for hours.","e1t":"İtfaiyeciler alevlerle saatlerce mücadele etti.","e2":"Blaze of glory.","e2t":"Şan ve şeref parıltısı."},{"w":"bleed","tr":"kanamak","te":"Verb","tt":"Fiil","de":"To lose blood from the body","dt":"Vücuttan kan kaybetmek","e1":"Your nose is bleeding.","e1t":"Burnun kanıyor.","e2":"Bleeding heart.","e2t":"Yufka yürekli."},{"w":"blend","tr":"harmanlamak / karışım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To mix different things together","dt":"Farklı şeyleri birbirine karıştırmak","e1":"This tea is a blend of different leaves.","e1t":"Bu çay, farklı yaprakların bir karışımıdır.","e2":"You should blend the ingredients until smooth.","e2t":"Malzemeleri pürüzsüz olana kadar karıştırmalısın (harmanlamalısın)."},{"w":"bless","tr":"kutsamak / lütfetmek","te":"Verb","tt":"Fiil","de":"To ask for God's help or protection","dt":"Tanrı'nın yardımını veya korumasını dilemek","e1":"God bless you!","e1t":"Çok yaşa! (Tanrı seni kutsasın!)","e2":"They were blessed with three children.","e2t":"Üç çocukla lütfendirildiler (çocukları oldu)."},{"w":"blink","tr":"göz kırpmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shut and open the eyes quickly","dt":"Gözleri hızla kapatıp açmak","e1":"She blinked in the bright sunlight.","e1t":"Parlak güneş ışığında gözlerini kırpıştırdı.","e2":"In the blink of an eye.","e2t":"Göz açıp kapayıncaya kadar."},{"w":"blister","tr":"su toplaması (deri)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small bubble on the skin filled with liquid","dt":"Deride içi sıvı dolu küçük kabarcık","e1":"I have a blister on my heel.","e1t":"Topuğumda bir su toplaması var.","e2":"Blood blister.","e2t":"Kan oturması."},{"w":"blockade","tr":"abluka / kuşatma","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act of sealing off a place to prevent goods from entering","dt":"Giriş çıkışı engellemek için bir yerin kapatılması","e1":"The navy established a blockade.","e1t":"Donanma abluka kurdu.","e2":"Economic blockade.","e2t":"Ekonomik abluka."},{"w":"blond / blonde","tr":"sarışın","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having fair or pale yellow hair","dt":"Açık veya soluk sarı saçlı","e1":"She has long blonde hair.","e1t":"Onun uzun sarı saçları var.","e2":"Strawberry blond.","e2t":"Kızıl sarışın."},{"w":"bloom","tr":"çiçek açmak / çiçek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce flowers; a flower","dt":"Çiçek açmak; çiçek","e1":"The roses are in full bloom.","e1t":"Güller tam açmış durumda.","e2":"Spring bloom.","e2t":"Bahar çiçeklenmesi."},{"w":"blot","tr":"leke / kurutmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A dark mark or stain; or to dry with absorbent paper","dt":"Koyu iz veya leke; veya emici kağıtla kurutmak","e1":"There is an ink blot on the paper.","e1t":"Kağıtta bir mürekkep lekesi var.","e2":"Blotting paper.","e2t":"Kurutma kağıdı."},{"w":"blur","tr":"bulanıklaştırmak / leke","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something difficult to see clearly","dt":"Bir şeyin net görülmesini zorlaştırmak","e1":"The rain blurred my vision.","e1t":"Yağmur görüşümü bulanıklaştırdı.","e2":"Everything was a blur without my glasses.","e2t":"Gözlüklerim olmadan her şey bir bulanıklıktı."},{"w":"boarder","tr":"yatılı öğrenci / kiracı","te":"Noun","tt":"İsim","de":"A person who receives regular meals and a room in another's house","dt":"Başkasının evinde oda ve yemek karşılığı kalan kişi","e1":"He was a boarder at a private school.","e1t":"Özel bir okulda yatılı öğrenciydi.","e2":"Skate boarder.","e2t":"Kaykaycı."},{"w":"boarding","tr":"biniş (uçak/gemi) / yatılı kalma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The action of getting on a ship, train, or aircraft","dt":"Gemi, tren veya uçağa binme işlemi","e1":"Boarding will start in ten minutes.","e1t":"Biniş on dakika içinde başlayacak.","e2":"Boarding school.","e2t":"Yatılı okul."},{"w":"boast","tr":"övünmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To talk with excessive pride about oneself","dt":"Kendisi hakkında aşırı gururla konuşmak","e1":"He is always boasting about his car.","e1t":"Her zaman arabasıyla övünüyor.","e2":"Boastful person.","e2t":"Kendini öven kişi."},{"w":"bold","tr":"cesur / belirgin / (matbaacılık) koyu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Brave and confident; or thick type","dt":"Cesur ve kendine güvenen; veya kalın yazı","e1":"It was a bold decision to quit.","e1t":"İstifa etmek cesurca bir karardı.","e2":"Bold text.","e2t":"Koyu (bold) metin."},{"w":"bonus","tr":"prim / ikramiye / artı avantaj","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An extra amount of money given as a reward","dt":"Ödül olarak verilen fazladan para","e1":"The company gave us a Christmas bonus.","e1t":"Şirket bize Noel ikramiyesi verdi.","e2":"Added bonus.","e2t":"Ekstra avantaj."},{"w":"boom","tr":"patlama (ekonomik/ses)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A period of sudden growth or a loud sound","dt":"Ani büyüme dönemi veya yüksek ses","e1":"There was an economic boom in the 1990s.","e1t":"1990'larda ekonomik bir patlama (büyüme) vardı.","e2":"I heard a loud boom in the distance.","e2t":"Uzakta büyük bir patlama sesi duydum."},{"w":"boost","tr":"artırmak / desteklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To improve or increase something","dt":"Bir şeyi iyileştirmek veya artırmak","e1":"We need to boost sales this month.","e1t":"Bu ay satışları artırmalıyız.","e2":"The victory boosted the team's confidence.","e2t":"Galibiyet takımın güvenini artırdı."},{"w":"booty","tr":"ganimet","te":"Noun","tt":"İsim","de":"Valuable stolen goods, especially those seized in war","dt":"Savaşta ele geçirilen değerli çalıntı eşyalar","e1":"The pirates shared the booty.","e1t":"Korsanlar ganimeti paylaştı.","e2":"Pirate's booty.","e2t":"Korsan ganimeti."},{"w":"booze","tr":"içki / içki içmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Alcoholic drink","dt":"Alkollü içki","e1":"He spent all his money on booze.","e1t":"Tüm parasını içkiye harcadı.","e2":"Booze cruise.","e2t":"İçkili tekne turu."},{"w":"borderline","tr":"sınır çizgisi / belirsiz","te":"Noun/Adjective/Adverb","tt":"A line marking a boundary; or barely acceptable","de":"Sınırı belirleyen çizgi; veya kabul edilebilirliğin tam sınırında","dt":"His behavior is borderline criminal.","e1":"Davranışı suç sınırında.","e1t":"Borderline pass.","e2":"Sınırda (ucu ucuna) geçiş.","e2t":""},{"w":"breach","tr":"ihlal / gedik","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act of breaking a law, promise, or agreement","dt":"Bir yasayı, sözü veya anlaşmayı bozma eylemi","e1":"This is a serious breach of contract.","e1t":"Bu, sözleşmenin ciddi bir ihlalidir.","e2":"There was a breach in security.","e2t":"Güvenlikte bir gedik (açık) vardı."},{"w":"breakdown","tr":"arıza / bozulma / detaylandırma","te":"Noun","tt":"İsim","de":"A mechanical failure or a loss of control","dt":"Mekanik bir arıza veya kontrol kaybı","e1":"My car had a breakdown on the highway.","e1t":"Arabam otoyolda arıza yaptı.","e2":"We need a breakdown of the costs.","e2t":"Maliyetlerin bir dökümüne (detayına) ihtiyacımız var."},{"w":"broaden","tr":"genişletmek","te":"Verb","tt":"Fiil","de":"To become wider or to increase knowledge","dt":"Genişlemek veya bilgiyi artırmak","e1":"Travel broadens the mind.","e1t":"Seyahat etmek zihni genişletir.","e2":"We need to broaden our product range.","e2t":"Ürün yelpazemizi genişletmemiz gerekiyor."},{"w":"broker","tr":"komisyoncu / aracı","te":"Noun","tt":"İsim","de":"A person who buys and sells for others","dt":"Başkaları adına alım satım yapan kişi","e1":"He works as a stock broker.","e1t":"Borsa komisyoncusu olarak çalışıyor.","e2":"You should talk to an insurance broker.","e2t":"Bir sigorta aracısıyla konuşmalısın."},{"w":"carefree","tr":"tasasız / dertsiz","te":"Adjective","tt":"Sıfat","de":"Having no worries or problems","dt":"Hiçbir endişesi veya sorunu olmama","e1":"I miss my carefree childhood days.","e1t":"Tasasız çocukluk günlerimi özlüyorum.","e2":"She has a carefree attitude toward life.","e2t":"Hayata karşı dertsiz bir tutumu var."},{"w":"cast","tr":"oyuncu kadrosu / atmak / döküm","te":"Noun/Verb","tt":"İsim/Fiil","de":"The actors in a play/film or to throw","dt":"Bir oyun/filmdeki oyuncular veya fırlatmak","e1":"The entire cast performed brilliantly.","e1t":"Tüm oyuncu kadrosu harika bir performans sergiledi.","e2":"He cast the net into the sea.","e2t":"Ağı denize attı."},{"w":"cease","tr":"durdurmak / kesmek","te":"Verb","tt":"Fiil","de":"To stop something from happening or existing","dt":"Bir şeyin olmasını veya var olmasını durdurmak","e1":"The company ceased operations last year.","e1t":"Şirket geçen yıl faaliyetlerini durdurdu.","e2":"The rain has finally ceased.","e2t":"Yağmur sonunda kesildi."},{"w":"challenging","tr":"zorlayıcı / çetin","te":"Adjective","tt":"Sıfat","de":"Difficult in an interesting or enjoyable way","dt":"İlginç veya keyifli bir şekilde zor olan","e1":"Teaching is a very challenging job.","e1t":"Öğretmenlik çok zorlayıcı bir iştir.","e2":"It was a challenging task, but we finished it.","e2t":"Zorlayıcı bir görevdi ama bitirdik."},{"w":"chant","tr":"tempo tutmak / ilahi / slogan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To repeat or sing a word or phrase many times","dt":"Bir kelime veya ifadeyi defalarca tekrarlamak veya söylemek","e1":"The crowd began to chant the player's name.","e1t":"Kalabalık, oyuncunun adını tempo tutarak söylemeye başladı.","e2":"They were shouting peace chants.","e2t":"Barış sloganları (ilahileri) söylüyorlardı."},{"w":"characterize","tr":"tanımlamak / nitelendirmek","te":"Verb","tt":"Fiil","de":"To describe the typical qualities of something","dt":"Bir şeyin tipik özelliklerini tarif etmek","e1":"High inflation characterizes this period.","e1t":"Bu dönemi yüksek enflasyon nitelendirir.","e2":"How would you characterize his style?","e2t":"Onun tarzını nasıl tanımlarsın?"},{"w":"charming","tr":"çekici / büyüleyici","te":"Adjective","tt":"Sıfat","de":"Very pleasant or attractive","dt":"Çok hoş veya çekici","e1":"What a charming little village!","e1t":"Ne kadar çekici küçük bir köy!","e2":"He is a charming person.","e2t":"O büyüleyici (nazik ve hoş) biridir."},{"w":"cheer","tr":"neşelendirmek / tezahürat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give a shout of encouragement or to make happy","dt":"Destek vermek için bağırmak veya mutlu etmek","e1":"The crowd cheered for the team.","e1t":"Kalabalık takım için tezahürat yaptı.","e2":"I bought flowers to cheer her up.","e2t":"Onu neşelendirmek için çiçek aldım."},{"w":"civilian","tr":"sivil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is not a member of the police or army","dt":"Polis veya ordu üyesi olmayan kişi","e1":"Many civilians were injured in the war.","e1t":"Savaşta birçok sivil yaralandı.","e2":"He left the army and returned to civilian life.","e2t":"Ordudan ayrıldı ve sivil hayata döndü."},{"w":"clarify","tr":"netleştirmek / açıklığa kavuşturmak","te":"Verb","tt":"Fiil","de":"To make something clear or easier to understand","dt":"Bir şeyi net veya anlaşılması daha kolay hale getirmek","e1":"Could you clarify that point?","e1t":"Şu noktayı netleştirebilir misiniz?","e2":"I need to clarify my position on this issue.","e2t":"Bu konudaki pozisyonumu açıklığa kavuşturmam gerekiyor."},{"w":"classify","tr":"sınıflandırmak","te":"Verb","tt":"Fiil","de":"To put things into groups based on their type","dt":"Şeyleri türlerine göre gruplara ayırmak","e1":"Books are classified by subject.","e1t":"Kitaplar konularına göre sınıflandırılır.","e2":"Biologists classify animals into different groups.","e2t":"Biyologlar hayvanları farklı gruplara ayırırlar."},{"w":"clause","tr":"madde / cümlecik","te":"Noun","tt":"İsim","de":"A part of a legal document or a part of a sentence","dt":"Bir yasal belgenin parçası veya bir cümlenin parçası","e1":"There is an important clause in the contract.","e1t":"Sözleşmede önemli bir madde var.","e2":"A relative clause provides more information.","e2t":"Bir ilgi cümleciği (relative clause) daha fazla bilgi sağlar."},{"w":"cling","tr":"tutunmak / yapışmak","te":"Verb","tt":"Fiil","de":"To hold on tightly to something","dt":"Bir şeye sıkıca tutunmak","e1":"The baby clung to his mother.","e1t":"Bebek annesine tutundu.","e2":"Wet clothes cling to the body.","e2t":"Islak kıyafetler vücuda yapışır."},{"w":"clinical","tr":"klinik","te":"Adjective","tt":"Sıfat","de":"Relating to the medical treatment of people","dt":"İnsanların tıbbi tedavisiyle ilgili","e1":"They are doing clinical trials for the new drug.","e1t":"Yeni ilaç için klinik araştırmalar yapıyorlar.","e2":"She has a clinical depression.","e2t":"Klinik bir depresyonu var."},{"w":"coastline","tr":"kıyı şeridi","te":"Noun","tt":"İsim","de":"The shape of the coast as seen from above","dt":"Yukarıdan görüldüğü şekliyle kıyının biçimi","e1":"Turkey has a very long coastline.","e1t":"Türkiye'nin çok uzun bir kıyı şeridi vardır.","e2":"We drove along the beautiful coastline.","e2t":"Güzel kıyı şeridi boyunca sürdük."},{"w":"commodity","tr":"emtia / ticari mal","te":"Noun","tt":"İsim","de":"A raw material or primary product that can be bought","dt":"Satın alınabilen hammadde veya temel ürün","e1":"Oil is a valuable commodity.","e1t":"Petrol değerli bir emtiadır.","e2":"Agricultural commodities include wheat and corn.","e2t":"Tarımsal emtialar buğday ve mısırı içerir."},{"w":"companion","tr":"arkadaş / yoldaş","te":"Noun","tt":"İsim","de":"A person you spend a lot of time with","dt":"Birlikte çok zaman geçirdiğiniz kişi","e1":"He was my traveling companion.","e1t":"O benim seyahat arkadaşımdı.","e2":"Dogs are great companions.","e2t":"Köpekler harika dostlardır (yoldaşlardır)."},{"w":"comparable","tr":"kıyaslanabilir / benzer","te":"Adjective","tt":"Sıfat","de":"Similar in size, amount, or quality","dt":"Boyut, miktar veya kalite bakımından benzer","e1":"The two situations are not comparable.","e1t":"İki durum kıyaslanabilir değil.","e2":"We need a comparable product.","e2t":"Benzer (kıyaslanabilir) bir ürüne ihtiyacımız var."},{"w":"compassion","tr":"merhamet / şefkat","te":"Noun","tt":"İsim","de":"A strong feeling of sympathy for people who suffer","dt":"Acı çeken insanlar için duyulan güçlü sempati","e1":"He showed great compassion for the poor.","e1t":"Fakirlere karşı büyük bir merhamet gösterdi.","e2":"Nurses must have compassion.","e2t":"Hemşirelerin şefkati olmalıdır."},{"w":"compensate","tr":"telafi etmek / tazminat ödemek","te":"Verb","tt":"Fiil","de":"To provide something good to balance something bad","dt":"Kötü bir şeyi dengelemek için iyi bir şey sağlamak","e1":"Nothing can compensate for the loss of a loved one.","e1t":"Hiçbir şey sevilen birinin kaybını telafi edemez.","e2":"They compensated him for his injuries.","e2t":"Yaralanmaları için ona tazminat ödediler."},{"w":"complement","tr":"tamamlamak / bütünlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something else seem better or more complete","dt":"Başka bir şeyin daha iyi veya daha tam görünmesini sağlamak","e1":"This wine complements the meat perfectly.","e1t":"Bu şarap eti mükemmel bir şekilde tamamlıyor.","e2":"The team has its full complement of players.","e2t":"Takımın tam oyuncu kadrosu (tamamlayıcısı) mevcut."},{"w":"composition","tr":"kompozisyon / yapı / eser","te":"Noun","tt":"İsim","de":"The way something is put together or a piece of art","dt":"Bir şeyin bir araya getirilme biçimi veya bir sanat eseri","e1":"He is studying musical composition.","e1t":"Müzik kompozisyonu (beste) çalışıyor.","e2":"What is the chemical composition of water?","e2t":"Suyun kimyasal yapısı nedir?"},{"w":"comprehensive","tr":"kapsamlı / detaylı","te":"Adjective","tt":"Sıfat","de":"Including everything that is necessary","dt":"Gerekli olan her şeyi içeren","e1":"We need a comprehensive study of the problem.","e1t":"Sorunla ilgili kapsamlı bir çalışmaya ihtiyacımız var.","e2":"He gave me a comprehensive list.","e2t":"Bana kapsamlı bir liste verdi."},{"w":"comprise","tr":"içermek /","te":"den oluşmak","tt":"Verb","de":"Fiil","dt":"To consist of or be made up of","e1":"","e1t":"den oluşmak veya meydana gelmek","e2":"The committee comprises ten members.","e2t":"Komite on üyeden oluşur."},{"w":"compromise","tr":"uzlaşmak / taviz vermek","te":"Verb/Noun","tt":"Fiil/İsim","de":"An agreement where both sides give up something","dt":"Her iki tarafın da bir şeylerden vazgeçtiği bir anlaşma","e1":"We finally reached a compromise.","e1t":"Sonunda bir uzlaşmaya vardık.","e2":"I won't compromise on quality.","e2t":"Kaliteden taviz vermeyeceğim."},{"w":"compute","tr":"hesaplamak","te":"Verb","tt":"Fiil","de":"To calculate an answer or amount using math","dt":"Matematik kullanarak bir cevabı veya miktarı hesaplamak","e1":"The results are computed by the computer.","e1t":"Sonuçlar bilgisayar tarafından hesaplanıyor.","e2":"We need to compute the total cost.","e2t":"Toplam maliyeti hesaplamamız gerekiyor."},{"w":"confess","tr":"itiraf etmek","te":"Verb","tt":"Fiil","de":"To admit that you have done something wrong","dt":"Yanlış bir şey yaptığını kabul etmek","e1":"He confessed to the crime.","e1t":"Suçu itiraf etti.","e2":"I must confess, I don't like his style.","e2t":"İtiraf etmeliyim ki onun tarzını sevmiyorum."},{"w":"confront","tr":"yüzleşmek / karşı karşıya gelmek","te":"Verb","tt":"Fiil","de":"To face or deal with a difficult situation or person","dt":"Zor bir durum veya kişiyle yüzleşmek veya ilgilenmek","e1":"We must confront our fears.","e1t":"Korkularımızla yüzleşmeliyiz.","e2":"He confronted the thief.","e2t":"Hırsızla karşı karşıya geldi."},{"w":"congress","tr":"kongre","te":"Noun","tt":"İsim","de":"A formal meeting or a law","dt":"making body","e1":"Resmi bir toplantı veya yasa yapan kurum","e1t":"He is a member of Congress.","e2":"O, Kongre üyesidir.","e2t":"The medical congress was held in Antalya."},{"w":"consent","tr":"onay / izin / razı olmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Permission or agreement","dt":"İzin veya anlaşma","e1":"You need parental consent to go.","e1t":"Gitmek için veli onayına (iznine) ihtiyacın var.","e2":"He finally consented to the plan.","e2t":"Sonunda plana razı oldu."},{"w":"conspiracy","tr":"komplo","te":"Noun","tt":"İsim","de":"A secret plan by a group to do something harmful","dt":"Bir grubun zararlı bir şey yapmak için kurduğu gizli plan","e1":"They were accused of conspiracy to murder.","e1t":"Cinayet komplosuyla suçlandılar.","e2":"I don't believe in conspiracy theories.","e2t":"Komplo teorilerine inanmam."},{"w":"constitute","tr":"oluşturmak / teşkil etmek","te":"Verb","tt":"Fiil","de":"To be or be considered as something","dt":"Bir şey olmak veya bir şey olarak kabul edilmek","e1":"Women constitute 50% of the workforce.","e1t":"Kadınlar iş gücünün %50'sini oluşturur.","e2":"This action constitutes a crime.","e2t":"Bu eylem bir suç teşkil eder."},{"w":"constraint","tr":"kısıtlama / baskı","te":"Noun","tt":"İsim","de":"Something that limits what you can do","dt":"Ne yapabileceğinizi sınırlayan şey","e1":"Time constraints made the task difficult.","e1t":"Zaman kısıtlamaları görevi zorlaştırdı.","e2":"We are working under financial constraints.","e2t":"Finansal kısıtlamalar altında çalışıyoruz."},{"w":"constructive","tr":"yapıcı","te":"Adjective","tt":"Sıfat","de":"Useful and intended to help or improve","dt":"Yararlı ve yardım etmeyi veya geliştirmeyi amaçlayan","e1":"Thank you for your constructive criticism.","e1t":"Yapıcı eleştiriniz için teşekkürler.","e2":"We had a constructive meeting.","e2t":"Yapıcı bir toplantı gerçekleştirdik."},{"w":"contemplate","tr":"düşünmek / tasarlamak","te":"Verb","tt":"Fiil","de":"To spend time considering a possible future action","dt":"Olası bir gelecekteki eylemi değerlendirmek için zaman harcamak","e1":"He is contemplating moving to Europe.","e1t":"Avrupa'ya taşınmayı düşünüyor (tasarlıyor).","e2":"I contemplated leaving my job.","e2t":"İşimden ayrılmayı düşündüm."},{"w":"contend","tr":"mücadele etmek / iddia etmek","te":"Verb","tt":"Fiil","de":"To compete or to state that something is true","dt":"Rekabet etmek veya bir şeyin doğru olduğunu belirtmek","e1":"He had to contend with many problems.","e1t":"Birçok sorunla mücadele etmek zorunda kaldı.","e2":"The lawyer contended that his client was innocent.","e2t":"Avukat, müvekkilinin masum olduğunu iddia etti."},{"w":"contradict","tr":"çelişmek / yalanlamak","te":"Verb","tt":"Fiil","de":"To say the opposite of what someone else has said","dt":"Başkasının söylediğinin aksini söylemek","e1":"Your actions contradict your words.","e1t":"Eylemlerin sözlerinle çelişiyor.","e2":"He contradicted the official report.","e2t":"Resmi raporu yalanladı (aksini söyledi)."},{"w":"contrary","tr":"zıt / aksine","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Completely different or opposite","dt":"Tamamen farklı veya zıt","e1":"On the contrary, I enjoyed the movie.","e1t":"Aksine, filmden zevk aldım.","e2":"Contrary to popular belief, he is very kind.","e2t":"Yaygın inanışın aksine, o çok naziktir."},{"w":"controversial","tr":"tartışmalı","te":"Adjective","tt":"Sıfat","de":"Causing a lot of disagreement or discussion","dt":"Çok fazla anlaşmazlığa veya tartışmaya neden olan","e1":"It was a controversial decision.","e1t":"Tartışmalı bir karardı.","e2":"Abortions are a controversial topic.","e2t":"Kürtaj tartışmalı bir konudur."},{"w":"convenience","tr":"kolaylık / uygunluk","te":"Noun","tt":"İsim","de":"The state of being suitable or useful","dt":"Uygun veya yararlı olma durumu","e1":"I like the convenience of online shopping.","e1t":"İnternet alışverişinin kolaylığını seviyorum.","e2":"Please call me at your convenience.","e2t":"Lütfen uygun olduğunuzda beni arayın."},{"w":"converge","tr":"birleşmek / aynı noktada buluşmak","te":"Verb","tt":"Fiil","de":"To move toward the same point","dt":"Aynı noktaya doğru hareket etmek","e1":"The two roads converge at the city center.","e1t":"İki yol şehir merkezinde birleşiyor.","e2":"Our opinions began to converge.","e2t":"Fikirlerimiz aynı noktada buluşmaya başladı."},{"w":"convey","tr":"iletmek / taşımak","te":"Verb","tt":"Fiil","de":"To express a thought or feeling; to transport","dt":"Bir düşünceyi veya duyguyu ifade etmek; taşımak","e1":"Please convey my regards to your father.","e1t":"Lütfen babana selamlarımı ilet.","e2":"This movie conveys a strong message.","e2t":"Bu film güçlü bir mesaj iletiyor."},{"w":"convict","tr":"suçlu bulmak / mahkum","te":"Verb/Noun","tt":"Fiil/İsim","de":"To decide officially that someone is guilty","dt":"Birinin suçlu olduğuna resmi olarak karar vermek","e1":"He was convicted of robbery.","e1t":"Soygundan suçlu bulundu (mahkum edildi).","e2":"The convict escaped from prison.","e2t":"Mahkum hapishaneden kaçtı."},{"w":"correlate","tr":"ilişkilendirmek","te":"Verb","tt":"Fiil","de":"To show a connection between two things","dt":"İki şey arasındaki bağlantıyı göstermek","e1":"Stress levels often correlate with workload.","e1t":"Stres seviyeleri genellikle iş yüküyle ilişkilidir.","e2":"The two studies correlate closely.","e2t":"İki çalışma birbiriyle yakından ilişkilidir."},{"w":"correspond","tr":"karşılık gelmek / yazışmak","te":"Verb","tt":"Fiil","de":"To be similar or to communicate by letter","dt":"Benzer olmak veya mektupla iletişim kurmak","e1":"The numbers on the map correspond to the key.","e1t":"Haritadaki sayılar anahtara karşılık geliyor.","e2":"I correspond with my pen pal once a month.","e2t":"Mektup arkadaşımla ayda bir yazışırım."},{"w":"corruption","tr":"yolsuzluk / yozlaşma","te":"Noun","tt":"İsim","de":"Dishonest or illegal behavior by people in power","dt":"Güç sahibi kişilerin dürüst olmayan veya yasal olmayan davranışları","e1":"The government is fighting corruption.","e1t":"Hükümet yolsuzlukla savaşıyor.","e2":"Corruption ruins the economy.","e2t":"Yolsuzluk ekonomiyi mahveder."},{"w":"counselor","tr":"rehber / danışman","te":"Noun","tt":"İsim","de":"A person who gives advice, especially for problems","dt":"Özellikle sorunlar için tavsiye veren kişi","e1":"He is a marriage counselor.","e1t":"O bir evlilik danışmanıdır.","e2":"Talk to your school counselor.","e2t":"Okul rehberinle konuş."},{"w":"counterpart","tr":"denk / karşılık","te":"Noun","tt":"İsim","de":"A person or thing that has the same job as another","dt":"Başka biriyle aynı işe sahip olan kişi veya şey","e1":"The Turkish president met his French counterpart.","e1t":"Türk Cumhurbaşkanı Fransız mevkidaşıyla (denkiyle) görüştü.","e2":"This machine is better than its older counterpart.","e2t":"Bu makine eski karşılığından (versiyonundan) daha iyidir."},{"w":"countless","tr":"sayısız","te":"Adjective","tt":"Sıfat","de":"Too many to be counted","dt":"Sayılamayacak kadar çok","e1":"I've seen this movie countless times.","e1t":"Bu filmi sayısız kez izledim.","e2":"There are countless stars in the sky.","e2t":"Gökyüzünde sayısız yıldız var."},{"w":"countrywide","tr":"ülke çapında","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Existing or happening in all parts of a country","dt":"Bir ülkenin tüm kısımlarında var olan veya gerçekleşen","e1":"The protest was countrywide.","e1t":"Protesto ülke çapındaydı.","e2":"They launched a countrywide campaign.","e2t":"Ülke çapında bir kampanya başlattılar."},{"w":"courteous","tr":"nazik / saygılı","te":"Adjective","tt":"Sıfat","de":"Polite and respectful","dt":"Nazik ve saygılı","e1":"The hotel staff were very courteous.","e1t":"Otel personeli çok nazikti.","e2":"He gave a courteous reply.","e2t":"Nazikçe bir cevap verdi."},{"w":"crawl","tr":"sürünmek / emeklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move on hands and knees or very slowly","dt":"Eller ve dizler üzerinde veya çok yavaş hareket etmek","e1":"The baby is starting to crawl.","e1t":"Bebek emeklemeye başlıyor.","e2":"Traffic was crawling due to the accident.","e2t":"Kaza nedeniyle trafik sürünüyordu (çok yavaş ilerliyordu)."},{"w":"credibility","tr":"güvenilirlik","te":"Noun","tt":"İsim","de":"The quality of being trusted and believed in","dt":"Güvenilme ve inanılma özelliği","e1":"The scandal damaged his credibility.","e1t":"Skandal onun güvenilirliğine zarar verdi.","e2":"We need to establish our credibility.","e2t":"Güvenilirliğimizi sağlamalıyız."},{"w":"creep","tr":"sessizce ilerlemek / sokulmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move slowly and quietly","dt":"Yavaşça ve sessizce hareket etmek","e1":"I crept into the room so as not to wake him.","e1t":"Onu uyandırmamak için odaya sessizce süzüldüm.","e2":"Doubts began to creep into my mind.","e2t":"Zihnime şüpheler girmeye (sokulmaya) başladı."},{"w":"criterion","tr":"kriter / ölçüt","te":"Noun","tt":"İsim","de":"A standard used for judging something","dt":"Bir şeyi yargılamak için kullanılan standart","e1":"What is the main criterion for success?","e1t":"Başarı için ana kriter nedir?","e2":"Success is not the only criterion.","e2t":"Başarı tek ölçüt değildir."},{"w":"cry out","tr":"bağırmak / feryat etmek","te":"Verb","tt":"Fiil","de":"To shout loudly because of pain or fear","dt":"Acı veya korku nedeniyle yüksek sesle bağırmak","e1":"She cried out in pain.","e1t":"Acıyla bağırdı (feryat etti).","e2":"He cried out for help.","e2t":"Yardım için bağırdı."},{"w":"cultivate","tr":"yetiştirmek / geliştirmek","te":"Verb","tt":"Fiil","de":"To grow crops or to develop a skill/relationship","dt":"Mahsul yetiştirmek veya beceri/ilişki geliştirmek","e1":"They cultivate olives in this region.","e1t":"Bu bölgede zeytin yetiştiriyorlar.","e2":"He tried to cultivate a good relationship with his boss.","e2t":"Patronuyla iyi bir ilişki geliştirmeye çalıştı."},{"w":"curriculum","tr":"müfredat","te":"Noun","tt":"İsim","de":"The subjects studied in a school or college","dt":"Bir okul veya kolejde okutulan dersler","e1":"The school is changing its science curriculum.","e1t":"Okul fen müfredatını değiştiriyor.","e2":"Is coding part of the national curriculum?","e2t":"Kodlama ulusal müfredatın bir parçası mı?"},{"w":"cushion","tr":"yastık / yumuşatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A soft object for sitting or to soften an impact","dt":"Oturmak için yumuşak nesne veya darbeyi yumuşatmak","e1":"I need a cushion for my back.","e1t":"Sırtım için bir yastığa ihtiyacım var.","e2":"The grass cushioned his fall.","e2t":"Çimler onun düşüşünü yumuşattı."},{"w":"damp","tr":"nemli / rutubetli","te":"Adjective/Noun/Verb","tt":"Slightly wet, often in an unpleasant way","de":"Genellikle hoş olmayan bir şekilde hafif ıslak","dt":"The walls feel damp.","e1":"Duvarlar nemli hissettiriyor.","e1t":"Wipe the table with a damp cloth.","e2":"Masayı nemli bir bezle silin.","e2t":""},{"w":"dare","tr":"cesaret etmek / meydan okumak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be brave enough to do something","dt":"Bir şeyi yapacak kadar cesur olmak","e1":"How dare you speak to me like that!","e1t":"Bana bu şekilde konuşmaya nasıl cürret edersin!","e2":"I didn't dare to ask him.","e2t":"Ona sormaya cesaret edemedim."},{"w":"database","tr":"veri tabanı","te":"Noun","tt":"İsim","de":"A large amount of information stored on a computer","dt":"Bilgisayarda saklanan büyük miktarda bilgi","e1":"We need to update the customer database.","e1t":"Müşteri veri tabanını güncellememiz gerekiyor.","e2":"He is an expert in database management.","e2t":"Veri tabanı yönetimi konusunda uzmandır."},{"w":"deal with","tr":"başa çıkmak / ilgilenmek","te":"Verb","tt":"Fiil","de":"To take action to achieve something or solve a problem","dt":"Bir şeyi başarmak veya bir sorunu çözmek için eylemde bulunmak","e1":"How do you deal with stress?","e1t":"Stresle nasıl başa çıkarsın?","e2":"I have to deal with many customers every day.","e2t":"Her gün birçok müşteriyle ilgilenmek zorundayım."},{"w":"deception","tr":"aldatma / hile","te":"Noun","tt":"İsim","de":"The act of hiding the truth or making someone believe a lie","dt":"Gerçeği gizleme veya birini bir yalana inandırma eylemi","e1":"He was found guilty of deception.","e1t":"Aldatmacadan (hileden) suçlu bulundu.","e2":"Most magic tricks rely on deception.","e2t":"Çoğu sihirbazlık numarası aldatmaya dayanır."},{"w":"declaration","tr":"bildiri / beyan","te":"Noun","tt":"İsim","de":"An official announcement","dt":"Resmi bir duyuru","e1":"The Declaration of Independence.","e1t":"Bağımsızlık Bildirgesi.","e2":"Do you have anything to add to your customs declaration?","e2t":"Gümrük beyanınıza ekleyecek bir şeyiniz var mı?"},{"w":"dedication","tr":"adanmışlık / özveri","te":"Noun","tt":"İsim","de":"The willingness to give a lot of time and energy to something","dt":"Bir şeye çok fazla zaman ve enerji verme isteği","e1":"Success requires hard work and dedication.","e1t":"Başarı sıkı çalışma ve adanmışlık gerektirir.","e2":"She is known for her dedication to her students.","e2t":"Öğrencilerine olan özverisiyle tanınır."},{"w":"deficit","tr":"açık (bütçe vb.)","te":"Noun","tt":"İsim","de":"The amount by which money spent is more than money received","dt":"Harcanan paranın alınan paradan fazla olduğu miktar","e1":"The country has a huge trade deficit.","e1t":"Ülkenin devasa bir ticaret açığı var.","e2":"We need to reduce the budget deficit.","e2t":"Bütçe açığını azaltmalıyız."},{"w":"dental","tr":"dişlerle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the teeth","dt":"Dişlerle ilgili","e1":"I have a dental appointment at 3 PM.","e1t":"Saat 15:00'te diş randevum var.","e2":"Dental hygiene is important.","e2t":"Diş hijyeni önemlidir."},{"w":"despair","tr":"umutsuzluk / kahır","te":"Noun/Verb","tt":"İsim/Fiil","de":"The feeling that there is no hope","dt":"Hiç umut olmadığı hissi","e1":"He was in the depths of despair.","e1t":"Umutsuzluğun derinliklerindeydi.","e2":"Don't despair; we will find a solution.","e2t":"Umutsuzluğa kapılma; bir çözüm bulacağız."},{"w":"detriment","tr":"zarar / ziyan","te":"Noun","tt":"İsim","de":"Harm or damage","dt":"Zarar veya hasar","e1":"He worked long hours to the detriment of his health.","e1t":"Sağlığının zararına (pahasına) uzun saatler çalıştı.","e2":"These changes will be a detriment to the project.","e2t":"Bu değişiklikler proje için bir zarar (kayıp) olacak."},{"w":"dialogue","tr":"diyalog","te":"Noun","tt":"İsim","de":"Conversation between two or more people","dt":"İki veya daha fazla kişi arasındaki konuşma","e1":"The book is full of witty dialogue.","e1t":"Kitap nükteli diyaloglarla dolu.","e2":"We need a constructive dialogue between the parties.","e2t":"Taraflar arasında yapıcı bir diyaloğa ihtiyacımız var."},{"w":"digest","tr":"sindirmek / özet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break down food in the stomach","dt":"Midede yiyecekleri parçalamak","e1":"Some foods are difficult to digest.","e1t":"Bazı yiyeceklerin sindirilmesi zordur.","e2":"I read a digest of the news.","e2t":"Haberlerin bir özetini (derlemesini) okudum."},{"w":"dilemma","tr":"ikilem","te":"Noun","tt":"İsim","de":"A difficult situation with two choices","dt":"İki seçenekli zor bir durum","e1":"I am in a dilemma about which job to take.","e1t":"Hangi işi alacağım konusunda bir ikilemdeyim.","e2":"This presents a moral dilemma.","e2t":"Bu ahlaki bir ikilem sunuyor."},{"w":"diminish","tr":"azalmak / eksilmek","te":"Verb","tt":"Fiil","de":"To become less or smaller","dt":"Daha az veya daha küçük olmak","e1":"The noise diminished as the car drove away.","e1t":"Araba uzaklaştıkça gürültü azaldı.","e2":"We must not diminish his achievements.","e2t":"Onun başarılarını küçümsememeliyiz (azaltmamalıyız)."},{"w":"dine","tr":"akşam yemeği yemek","te":"Verb","tt":"Fiil","de":"To eat dinner","dt":"Akşam yemeği yemek","e1":"We dined at a fancy restaurant.","e1t":"Lüks bir restoranda akşam yemeği yedik.","e2":"He invites us to dine with him.","e2t":"Bizi onunla yemek yemeye davet ediyor."},{"w":"diploma","tr":"diploma","te":"Noun","tt":"İsim","de":"A document given by a school or college","dt":"Okul veya kolej tarafından verilen belge","e1":"She received her diploma yesterday.","e1t":"Diplomasını dün aldı.","e2":"A high school diploma is necessary for the job.","e2t":"İş için bir lise diploması gereklidir."},{"w":"diplomacy","tr":"diplomasi","te":"Noun","tt":"İsim","de":"The activity of managing international relations","dt":"Uluslararası ilişkileri yönetme faaliyeti","e1":"The crisis was solved through diplomacy.","e1t":"Kriz diplomasi yoluyla çözüldü.","e2":"He is an expert in international diplomacy.","e2t":"Uluslararası diplomasi konusunda uzmandır."},{"w":"directory","tr":"rehber / dizin","te":"Noun","tt":"İsim","de":"A list of names, addresses, or files","dt":"İsimlerin, adreslerin veya dosyaların listesi","e1":"Look up his number in the telephone directory.","e1t":"Numarasına telefon rehberinden bak.","e2":"The files are in the \"Documents\" directory.","e2t":"Dosyalar \"Belgeler\" dizininde."},{"w":"dispose","tr":"atmak / kurtulmak / yerleştirmek","te":"Verb","tt":"Fiil","de":"To get rid of something or to arrange","dt":"Bir şeyden kurtulmak veya düzenlemek/yerleştirmek","e1":"How should we dispose of the toxic waste?","e1t":"Toksik atığı nasıl atmalıyız (bertaraf etmeliyiz)?","e2":"He is disposed to help us.","e2t":"Bize yardım etmeye meyilli (hazır)."},{"w":"dispute","tr":"tartışma / anlaşmazlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong disagreement or argument","dt":"Güçlü bir anlaşmazlık veya tartışma","e1":"The two countries have a border dispute.","e1t":"İki ülkenin sınır anlaşmazlığı var.","e2":"They are disputing the results of the election.","e2t":"Seçim sonuçlarını tartışıyorlar (itiraz ediyorlar)."},{"w":"distract","tr":"dikkatini dağıtmak","te":"Verb","tt":"Fiil","de":"To take someone's attention away from something","dt":"Birinin dikkatini bir şeyden uzaklaştırmak","e1":"Don't distract me while I am driving.","e1t":"Araba sürerken dikkatimi dağıtma.","e2":"The noise distracted him from his work.","e2t":"Gürültü onun dikkatini işinden uzaklaştırdı."},{"w":"diverse","tr":"çeşitli / türlü","te":"Adjective","tt":"Sıfat","de":"Including many different types","dt":"Birçok farklı türü içeren","e1":"Istanbul has a very diverse population.","e1t":"İstanbul'un çok çeşitli bir nüfusu var.","e2":"We have diverse interests.","e2t":"Çeşitli ilgi alanlarımız var."},{"w":"diversity","tr":"çeşitlilik","te":"Noun","tt":"İsim","de":"The state of being diverse; variety","dt":"Çeşitli olma durumu; çeşitlilik","e1":"Cultural diversity is important for a society.","e1t":"Kültürel çeşitlilik bir toplum için önemlidir.","e2":"There is a great diversity of plants in the forest.","e2t":"Ormanda büyük bir bitki çeşitliliği var."},{"w":"drift","tr":"sürüklenmek / akıntı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be carried along by currents of air or water","dt":"Hava veya su akıntıları tarafından taşınmak","e1":"The boat began to drift out to sea.","e1t":"Tekne denize doğru sürüklenmeye başladı.","e2":"I could feel myself drifting off to sleep.","e2t":"Uykuya daldığımı (sürüklendiğimi) hissedebiliyordum."},{"w":"duration","tr":"süre / müddet","te":"Noun","tt":"İsim","de":"The length of time that something lasts","dt":"Bir şeyin sürdüğü zamanın uzunluğu","e1":"The duration of the flight is four hours.","e1t":"Uçuşun süresi dört saattir.","e2":"You must stay here for the duration of the course.","e2t":"Kurs süresince burada kalmalısınız."},{"w":"dusty","tr":"tozlu","te":"Adjective","tt":"Sıfat","de":"Covered with dust","dt":"Tozla kaplı","e1":"These books are very dusty.","e1t":"Bu kitaplar çok tozlu.","e2":"We drove down a dusty road.","e2t":"Tozlu bir yoldan sürdük."},{"w":"dwelling","tr":"konut / ev","te":"Noun","tt":"İsim","de":"A house or place to live in","dt":"Bir ev veya yaşanacak yer","e1":"This is a private dwelling.","e1t":"Burası özel bir konuttur.","e2":"Ancient cave dwellings are interesting.","e2t":"Antik mağara konutları ilginçtir."},{"w":"embarrass","tr":"utandırmak","te":"Verb","tt":"Fiil","de":"To make someone feel ashamed or shy","dt":"Birini utanmış veya mahcup hissettirmek","e1":"I didn't mean to embarrass you.","e1t":"Seni utandırmak istememiştim.","e2":"His behavior embarrassed his parents.","e2t":"Onun davranışı ailesini utandırdı."},{"w":"emerge","tr":"ortaya çıkmak / çıkmak","te":"Verb","tt":"Fiil","de":"To appear or come out from somewhere","dt":"Bir yerden görünmek veya çıkmak","e1":"The sun emerged from behind the clouds.","e1t":"Güneş bulutların arkasından ortaya çıktı.","e2":"New details began to emerge.","e2t":"Yeni detaylar ortaya çıkmaya başladı."},{"w":"empirical","tr":"deneysel / ampirik","te":"Adjective","tt":"Sıfat","de":"Based on what is experienced or seen","dt":"Deneyime veya görülene dayalı","e1":"We need empirical evidence.","e1t":"Deneysel (gözleme dayalı) kanıta ihtiyacımız var.","e2":"His theory is supported by empirical data.","e2t":"Teorisi ampirik verilerle destekleniyor."},{"w":"enforce","tr":"uygulamak / zorlamak","te":"Verb","tt":"Fiil","de":"To make people obey a law or rule","dt":"İnsanların bir yasaya veya kurala uymasını sağlamak","e1":"The police enforce the law.","e1t":"Polis yasayı uygular (yürütür).","e2":"It is difficult to enforce this rule.","e2t":"Bu kuralı uygulamak zordur."},{"w":"enhance","tr":"geliştirmek / artırmak","te":"Verb","tt":"Fiil","de":"To improve the quality or value of something","dt":"Bir şeyin kalitesini veya değerini artırmak","e1":"This salt will enhance the flavor of the food.","e1t":"Bu tuz yemeğin lezzetini artıracaktır.","e2":"We are working to enhance our security.","e2t":"Güvenliğimizi geliştirmek için çalışıyoruz."},{"w":"enlighten","tr":"aydınlatmak / bilgilendirmek","te":"Verb","tt":"Fiil","de":"To give someone more knowledge or understanding","dt":"Birine daha fazla bilgi veya anlayış vermek","e1":"Can you enlighten me on this subject?","e1t":"Beni bu konuda aydınlatabilir misiniz?","e2":"A very enlightening book.","e2t":"Çok aydınlatıcı bir kitap."},{"w":"enquiry","tr":"sorgu / soruşturma / bilgi alma","te":"Noun","tt":"İsim","de":"A question that asks for information","dt":"Bilgi isteyen bir soru","e1":"We received many enquiries about the job.","e1t":"İşle ilgili birçok bilgi alma talebi (sorgusu) aldık.","e2":"The police are conducting an enquiry.","e2t":"Polis bir soruşturma yürütüyor."},{"w":"enroll","tr":"kaydolmak / yazılmak","te":"Verb","tt":"Fiil","de":"To officially join a school, course, or group","dt":"Bir okula, kursa veya gruba resmi olarak katılmak","e1":"I want to enroll in an English course.","e1t":"Bir İngilizce kursuna kaydolmak istiyorum.","e2":"They enrolled their children in a private school.","e2t":"Çocuklarını özel bir okula yazdırdılar."},{"w":"entitle","tr":"hak vermek / yetkilendirmek / isimlendirmek","te":"Verb","tt":"Fiil","de":"To give someone the right to do something","dt":"Birine bir şeyi yapma hakkı vermek","e1":"This ticket entitles you to a free meal.","e1t":"Bu bilet size ücretsiz bir yemek hakkı verir.","e2":"He entitled his book \"Success\".","e2t":"Kitabına \"Başarı\" adını verdi."},{"w":"entrepreneur","tr":"girişimci","te":"Noun","tt":"İsim","de":"Someone who starts their own business","dt":"Kendi işini kuran kişi","e1":"He is a successful technology entrepreneur.","e1t":"Başarılı bir teknoloji girişimcisidir.","e2":"Entrepreneurs create new jobs.","e2t":"Girişimciler yeni işler yaratır."},{"w":"envious","tr":"kıskanç","te":"Adjective","tt":"Sıfat","de":"Wanting something that someone else has","dt":"Başkasının sahip olduğu bir şeyi istemek","e1":"I am very envious of your success.","e1t":"Senin başarını çok kıskanıyorum (imreniyorum).","e2":"They were envious of his wealth.","e2t":"Onun zenginliğini kıskanıyorlardı."},{"w":"erect","tr":"dikmek / inşa etmek / dik","te":"Verb/Adjective","tt":"To build a structure or to stand upright","de":"Bir yapı inşa etmek veya dik durmak","dt":"They erected a statue in the park.","e1":"Parka bir heykel diktiler.","e1t":"Keep your back erect.","e2":"Sırtını dik tut.","e2t":""},{"w":"erupt","tr":"patlamak (yanardağ/öfke)","te":"Verb","tt":"Fiil","de":"To explode or to start suddenly","dt":"Patlamak veya aniden başlamak","e1":"The volcano erupted yesterday.","e1t":"Yanardağ dün patladı.","e2":"Violence erupted in the streets.","e2t":"Sokaklarda şiddet patlak verdi."},{"w":"essence","tr":"öz / esas","te":"Noun","tt":"İsim","de":"The most important part or quality of something","dt":"Bir şeyin en önemli parçası veya özelliği","e1":"The essence of the problem is money.","e1t":"Sorunun özü paradır.","e2":"Time is of the essence.","e2t":"Zaman en önemli esastır (vakit nakittir)."},{"w":"evident","tr":"açık / belli / aşikar","te":"Adjective","tt":"Sıfat","de":"Easily seen or understood","dt":"Kolayca görülen veya anlaşılan","e1":"It was evident that he was tired.","e1t":"Yorgun olduğu belliydi.","e2":"The benefits are evident.","e2t":"Faydaları aşikardır."},{"w":"exceed","tr":"aşmak / geçmek","te":"Verb","tt":"Fiil","de":"To be greater than a number or amount","dt":"Bir sayı veya miktardan daha fazla olmak","e1":"You must not exceed the speed limit.","e1t":"Hız sınırını aşmamalısınız.","e2":"The costs exceeded our budget.","e2t":"Maliyetler bütçemizi geçti."},{"w":"excellence","tr":"mükemmellik","te":"Noun","tt":"İsim","de":"The quality of being extremely good","dt":"Son derece iyi olma özelliği","e1":"The school is known for its academic excellence.","e1t":"Okul akademik mükemmelliğiyle tanınır.","e2":"He strives for excellence in everything.","e2t":"Her şeyde mükemmellik için çabalar."},{"w":"exclusive","tr":"özel / seçkin / hariç tutan","te":"Adjective","tt":"Sıfat","de":"Only for a limited group; not including others","dt":"Sadece sınırlı bir grup için; başkalarını dahil etmeyen","e1":"This is an exclusive interview.","e1t":"Bu özel bir röportajdır.","e2":"The hotel is very exclusive.","e2t":"Otel çok seçkindir (lüks ve özeldir)."},{"w":"execute","tr":"yürütmek / infaz etmek / idam etmek","te":"Verb","tt":"Fiil","de":"To do or perform something; to kill as punishment","dt":"Bir şeyi yapmak/yürütmek; ceza olarak öldürmek","e1":"They executed the plan perfectly.","e1t":"Planı mükemmel bir şekilde yürüttüler (uyguladılar).","e2":"The prisoner was executed yesterday.","e2t":"Mahkum dün idam edildi."},{"w":"exile","tr":"sürgün","te":"Noun/Verb","tt":"İsim/Fiil","de":"Being forced to live in another country","dt":"Başka bir ülkede yaşamaya zorlanma","e1":"He lived in exile for twenty years.","e1t":"Yirmi yıl sürgünde yaşadı.","e2":"The king was exiled to a small island.","e2t":"Kral küçük bir adaya sürgün edildi."},{"w":"expedition","tr":"keşif gezisi / sefer","te":"Noun","tt":"İsim","de":"An organized journey for a particular purpose","dt":"Belirli bir amaç için düzenlenen yolculuk","e1":"He led an expedition to the South Pole.","e1t":"Güney Kutbu'na bir keşif gezisi yönetti.","e2":"We are going on a shopping expedition.","e2t":"Bir alışveriş seferine çıkıyoruz."},{"w":"exploit","tr":"sömürmek / faydalanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To use someone or something unfairly for your own advantage","dt":"Birini veya bir şeyi kendi çıkarınız için adaletsizce kullanmak","e1":"Laws exist to stop companies from exploiting workers.","e1t":"Şirketlerin işçileri sömürmesini durdurmak için yasalar vardır.","e2":"He exploited every opportunity.","e2t":"Her fırsatı değerlendirdi (faydalandı)."},{"w":"exterior","tr":"dış / dış yüzey","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The outside part of something","dt":"Bir şeyin dış kısmı","e1":"The exterior of the building is made of stone.","e1t":"Binanın dışı taştan yapılmıştır.","e2":"He has a tough exterior but a kind heart.","e2t":"Sert bir dış görünüşü var ama kalbi nazik."},{"w":"fabric","tr":"kumaş / yapı","te":"Noun","tt":"İsim","de":"Cloth or the basic structure of something","dt":"Kumaş veya bir şeyin temel yapısı","e1":"This fabric is very soft.","e1t":"Bu kumaş çok yumuşak.","e2":"The fabric of society is changing.","e2t":"Toplumun yapısı değişiyor."},{"w":"facilitate","tr":"kolaylaştırmak","te":"Verb","tt":"Fiil","de":"To make something possible or easier","dt":"Bir şeyi mümkün veya daha kolay kılmak","e1":"The new system will facilitate communication.","e1t":"Yeni sistem iletişimi kolaylaştıracak.","e2":"Computers facilitate the processing of data.","e2t":"Bilgisayarlar verilerin işlenmesini kolaylaştırır."},{"w":"famine","tr":"kıtlık","te":"Noun","tt":"İsim","de":"A long period when there is very little food","dt":"Çok az yiyeceğin olduğu uzun dönem","e1":"Thousands of people died during the famine.","e1t":"Kıtlık sırasında binlerce kişi öldü.","e2":"The drought caused a widespread famine.","e2t":"Kuraklık yaygın bir kıtlığa neden oldu."},{"w":"fatigue","tr":"aşırı yorgunluk / bıkkınlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"Extreme tiredness","dt":"Aşırı yorgunluk","e1":"He was suffering from physical fatigue.","e1t":"Fiziksel yorgunluktan muzdaripti.","e2":"The long drive caused driver fatigue.","e2t":"Uzun sürüş sürücü yorgunluğuna neden oldu."},{"w":"feasible","tr":"yapılabilir / uygulanabilir","te":"Adjective","tt":"Sıfat","de":"Able to be made, done, or achieved","dt":"Yapılabilen, yapılabilen veya başarılabilen","e1":"It is not a feasible plan.","e1t":"Bu uygulanabilir bir plan değil.","e2":"Is it feasible to build a bridge here?","e2t":"Buraya köprü inşa etmek mümkün mü (yapılabilir mi)?"},{"w":"fellowship","tr":"arkadaşlık / cemiyet / burs","te":"Noun","tt":"İsim","de":"A feeling of friendship or an association","dt":"Arkadaşlık hissi veya bir dernek/cemiyet","e1":"They enjoy the fellowship of the club.","e1t":"Kulübün arkadaşlığından keyif alıyorlar.","e2":"He was awarded a research fellowship.","e2t":"Ona bir araştırma bursu verildi."},{"w":"fierce","tr":"sert / vahşi / şiddetli","te":"Adjective","tt":"Sıfat","de":"Physically violent and frightening; strong","dt":"Fiziksel olarak şiddetli ve korkutucu; güçlü","e1":"There was fierce competition between the two teams.","e1t":"İki takım arasında sert bir rekabet vardı.","e2":"A fierce dog was guarding the house.","e2t":"Evi vahşi bir köpek koruyordu."},{"w":"figure out","tr":"çözmek / anlamak","te":"Verb","tt":"Fiil","de":"To understand or solve something","dt":"Bir şeyi anlamak veya çözmek","e1":"I can't figure out how to use this machine.","e1t":"Bu makinenin nasıl kullanılacağını çözemiyorum.","e2":"We need to figure out a way to save money.","e2t":"Para biriktirmenin bir yolunu bulmalıyız (çözmeliyiz)."},{"w":"filter","tr":"filtre / süzgeç / süzmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for removing impurities; to pass through a filter","dt":"Safsızlıkları gidermek için bir araç; filtreden geçmek","e1":"The water goes through a charcoal filter.","e1t":"Su bir kömür filtresinden geçer.","e2":"The sunlight filtered through the leaves.","e2t":"Güneş ışığı yaprakların arasından süzüldü."},{"w":"finalize","tr":"sonlandırmak / kesinleştirmek","te":"Verb","tt":"Fiil","de":"To make a final decision or plan","dt":"Son kararı veya planı yapmak","e1":"We need to finalize the details of the contract.","e1t":"Sözleşmenin detaylarını kesinleştirmemiz gerekiyor.","e2":"They finalized the deal yesterday.","e2t":"Anlaşmayı dün sonlandırdılar."},{"w":"find out","tr":"öğrenmek / bulup çıkarmak","te":"Verb","tt":"Fiil","de":"To get information or to discover a fact","dt":"Bilgi edinmek veya bir gerçeği keşfetmek","e1":"I'll call the hotel to find out the price.","e1t":"Fiyatı öğrenmek için oteli arayacağım.","e2":"He found out that his flight was canceled.","e2t":"Uçuşunun iptal edildiğini öğrendi."},{"w":"fiscal","tr":"mali / parasal","te":"Adjective","tt":"Sıfat","de":"Relating to public money or taxes","dt":"Kamu parası veya vergilerle ilgili","e1":"The government announced a new fiscal policy.","e1t":"Hükümet yeni bir mali politika duyurdu.","e2":"The fiscal year ends in June.","e2t":"Mali yıl Haziran'da bitiyor."},{"w":"fishery","tr":"balıkçılık / balık çiftliği","te":"Noun","tt":"İsim","de":"The business of catching or breeding fish","dt":"Balık yakalama veya yetiştirme işi","e1":"The local fishery provides jobs for many people.","e1t":"Yerel balıkçılık birçok kişi için iş sağlıyor.","e2":"Overfishing is damaging the North Sea fisheries.","e2t":"Aşırı avlanma Kuzey Denizi balıkçılık alanlarına zarar veriyor."},{"w":"fist","tr":"yumruk","te":"Noun","tt":"İsim","de":"A hand with the fingers closed tightly","dt":"Parmakların sıkıca kapalı olduğu el","e1":"He hit the table with his fist.","e1t":"Masaya yumruğuyla vurdu.","e2":"Keep your fists clenched.","e2t":"Yumruklarını sıkılı tut."},{"w":"flatten","tr":"düzleştirmek / yassıltmak","te":"Verb","tt":"Fiil","de":"To make something flat or flatter","dt":"Bir şeyi düz veya daha düz hale getirmek","e1":"The storm flattened the crops.","e1t":"Fırtına mahsulleri dümdüz etti.","e2":"Use a roller to flatten the ground.","e2t":"Zemini düzleştirmek için bir silindir kullanın."},{"w":"flick","tr":"fiske / hızlı hareket / hafifçe vurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something with a sudden light movement","dt":"Bir şeyi ani ve hafif bir hareketle hareket ettirmek","e1":"He flicked the ash from his cigarette.","e1t":"Sigarasının külünü bir fiskeyle attı.","e2":"She flicked through the pages of the magazine.","e2t":"Derginin sayfalarına hızlıca göz attı."},{"w":"flip","tr":"çevirmek / döndürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn over quickly","dt":"Hızlıca ters çevirmek","e1":"Flip the pancake over.","e1t":"Pankeki ters çevir.","e2":"We flipped a coin to decide.","e2t":"Karar vermek için yazı tura attık (bozuk para çevirdik)."},{"w":"flourish","tr":"gelişmek / serpilmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To grow or develop successfully","dt":"Başarıyla büyümek veya gelişmek","e1":"The economy is beginning to flourish.","e1t":"Ekonomi gelişmeye başlıyor.","e2":"Plants flourish in this warm climate.","e2t":"Bitkiler bu sıcak iklimde serpilir."},{"w":"fluctuate","tr":"dalgalanmak / değişmek","te":"Verb","tt":"Fiil","de":"To change continually; to go up and down","dt":"Sürekli değişmek; inip çıkmak","e1":"Prices fluctuate daily.","e1t":"Fiyatlar günlük olarak dalgalanıyor.","e2":"His mood fluctuates between joy and sadness.","e2t":"Ruh hali neşe ve üzüntü arasında gidip geliyor (dalgalanıyor)."},{"w":"flush","tr":"kızarmak / sifonu çekmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become red in the face; to clean a toilet with water","dt":"Yüzün kızarması; tuvaleti suyla temizlemek","e1":"She flushed with embarrassment.","e1t":"Utancından yüzü kızardı.","e2":"Don't forget to flush the toilet.","e2t":"Tuvaletin sifonunu çekmeyi unutma."},{"w":"footage","tr":"video görüntüsü / çekim","te":"Noun","tt":"İsim","de":"Film or video of a particular event","dt":"Belirli bir olayın film veya video görüntüsü","e1":"The news showed footage of the earthquake.","e1t":"Haberler depremin görüntülerini gösterdi.","e2":"We have security camera footage of the theft.","e2t":"Hırsızlığın güvenlik kamerası görüntüleri var."},{"w":"foresee","tr":"öngörmek / tahmin etmek","te":"Verb","tt":"Fiil","de":"To know about something before it happens","dt":"Bir şeyi olmadan önce bilmek","e1":"I don't foresee any problems.","e1t":"Herhangi bir sorun öngörmüyorum.","e2":"It was impossible to foresee the future.","e2t":"Geleceği öngörmek imkansızdı."},{"w":"forge","tr":"şekil vermek / sahtesini yapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make an illegal copy or to form something","dt":"Yasadışı bir kopya yapmak veya bir şeyi oluşturmak","e1":"He forged his father's signature.","e1t":"Babasının imzasını taklit etti (sahtesini yaptı).","e2":"They are trying to forge a new agreement.","e2t":"Yeni bir anlaşma oluşturmaya (şekil vermeye) çalışıyorlar."},{"w":"forgetful","tr":"unutkan","te":"Adjective","tt":"Sıfat","de":"Often forgetting things","dt":"Sık sık bir şeyleri unutan","e1":"He is becoming very forgetful as he gets older.","e1t":"Yaşlandıkça çok unutkanlaşıyor.","e2":"I'm sorry, I'm so forgetful.","e2t":"Üzgünüm, çok unutkanım."},{"w":"formulate","tr":"formüle etmek / kurallaştırmak","te":"Verb","tt":"Fiil","de":"To develop a plan, system, or idea carefully","dt":"Bir planı, sistemi veya fikri dikkatlice geliştirmek","e1":"We need to formulate a new strategy.","e1t":"Yeni bir strateji formüle etmeliyiz.","e2":"The medicine is formulated for children.","e2t":"İlaç çocuklar için formüle edilmiştir."},{"w":"fort","tr":"kale / hisar","te":"Noun","tt":"İsim","de":"A strong building used by the army for defense","dt":"Ordunun savunma için kullandığı güçlü bina","e1":"They built a fort to protect the harbor.","e1t":"Limanı korumak için bir kale inşa ettiler.","e2":"The ruins of the old fort are still there.","e2t":"Eski kalenin kalıntıları hala orada."},{"w":"fossil","tr":"fosil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The remains of a prehistoric animal or plant","dt":"Tarih öncesi bir hayvan veya bitkinin kalıntıları","e1":"They found dinosaur fossils in the desert.","e1t":"Çölde dinozor fosilleri buldular.","e2":"Coal is a fossil fuel.","e2t":"Kömür bir fosil yakıttır."},{"w":"foster","tr":"büyütmek / teşvik etmek","te":"Verb/Adjective","tt":"To take care of a child or to encourage a feeling","de":"Bir çocuğa bakmak veya bir duyguyu teşvik etmek/geliştirmek","dt":"They foster two children.","e1":"İki çocuğa koruyucu ailelik yapıyorlar (büyütüyorlar).","e1t":"The teacher tried to foster a sense of community.","e2":"Öğretmen bir topluluk duygusu geliştirmeye çalıştı.","e2t":""},{"w":"fraction","tr":"kesir / küçük parça","te":"Noun","tt":"İsim","de":"A small part of something or a math term","dt":"Bir şeyin küçük bir parçası veya matematik terimi","e1":"I only paid a fraction of the original price.","e1t":"Orijinal fiyatın sadece küçük bir kısmını ödedim.","e2":"Can you simplify this fraction?","e2t":"Bu kesri sadeleştirebilir misin?"},{"w":"fracture","tr":"kırık / çatlak / kırılmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A break or crack in something hard, like a bone","dt":"Kemik gibi sert bir şeydeki kırılma veya çatlama","e1":"He has a fracture in his left arm.","e1t":"Sol kolunda bir kırık var.","e2":"The pipe fractured during the cold weather.","e2t":"Boru soğuk havada çatladı."},{"w":"fragile","tr":"kırılgan / hassas","te":"Adjective","tt":"Sıfat","de":"Easily broken or damaged","dt":"Kolayca kırılan veya zarar gören","e1":"Be careful, these glasses are fragile.","e1t":"Dikkatli ol, bu bardaklar kırılgandır.","e2":"The peace agreement is very fragile.","e2t":"Barış anlaşması çok hassas (kırılgan)."},{"w":"fragment","tr":"parça / kırıntı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of something that has broken off","dt":"Kopan veya kırılan küçük parça","e1":"She found fragments of glass on the floor.","e1t":"Yerde cam parçaları buldu.","e2":"The old empire fragmented into small states.","e2t":"Eski imparatorluk küçük devletlere bölündü (parçalandı)."},{"w":"fragrance","tr":"güzel koku / parfüm","te":"Noun","tt":"İsim","de":"A pleasant smell or a perfume","dt":"Hoş bir koku veya parfüm","e1":"The flowers have a beautiful fragrance.","e1t":"Çiçeklerin güzel bir kokusu var.","e2":"She is wearing a new fragrance.","e2t":"Yeni bir koku (parfüm) sürünmüş."},{"w":"frank","tr":"açık sözlü / dürüst","te":"Adjective","tt":"Sıfat","de":"Honest and direct in what you say","dt":"Söylediklerinde dürüst ve doğrudan olan","e1":"We had a very frank discussion.","e1t":"Çok açık sözlü bir tartışma yaptık.","e2":"To be frank, I don't like your idea.","e2t":"Dürüst olmak gerekirse, fikrini beğenmiyorum."},{"w":"fraud","tr":"dolandırıcılık / sahtekarlık","te":"Noun","tt":"İsim","de":"The crime of getting money by deceiving people","dt":"İnsanları aldatarak para kazanma suçu","e1":"He was arrested for credit card fraud.","e1t":"Kredi kartı dolandırıcılığından tutuklandı.","e2":"The whole thing was a fraud.","e2t":"Her şey bir sahtekarlıktı."},{"w":"freshwater","tr":"tatlı su","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to water that is not salty","dt":"Tuzlu olmayan suyla ilgili","e1":"Salmon live in both freshwater and saltwater.","e1t":"Somon balıkları hem tatlı suda hem de tuzlu suda yaşarlar.","e2":"A freshwater lake.","e2t":"Bir tatlı su gölü."},{"w":"friction","tr":"sürtünme / anlaşmazlık","te":"Noun","tt":"İsim","de":"The force that stops surfaces sliding or a disagreement","dt":"Yüzeylerin kaymasını durduran kuvvet veya anlaşmazlık","e1":"Friction causes heat.","e1t":"Sürtünme ısıya neden olur.","e2":"There is friction between the two neighbors.","e2t":"İki komşu arasında anlaşmazlık (sürtünme) var."},{"w":"fruitful","tr":"verimli / bereketli","te":"Adjective","tt":"Sıfat","de":"Producing good results","dt":"İyi sonuçlar üreten","e1":"We had a very fruitful meeting.","e1t":"Çok verimli bir toplantı yaptık.","e2":"It was a fruitful year for the company.","e2t":"Şirket için verimli bir yıldı."},{"w":"frustrate","tr":"hayal kırıklığına uğratmak / engellemek","te":"Verb","tt":"Fiil","de":"To make someone feel annoyed or less confident","dt":"Birini rahatsız hissettirmek veya güvenini azaltmak","e1":"The lack of progress frustrates me.","e1t":"İlerleme olmaması beni hayal kırıklığına uğratıyor (sinirlendiriyor).","e2":"His attempts were frustrated by the weather.","e2t":"Girişimleri hava durumu nedeniyle engellendi."},{"w":"frustration","tr":"hayal kırıklığı / hüsran","te":"Noun","tt":"İsim","de":"The feeling of being annoyed or discouraged","dt":"Rahatsızlık veya cesaret kırıklığı hissi","e1":"He screamed in frustration.","e1t":"Hayal kırıklığıyla bağırdı.","e2":"I understand your frustration with the slow system.","e2t":"Yavaş sistemle ilgili yaşadığın hüsranı anlıyorum."},{"w":"full","tr":"time","te":"tam zamanlı","tt":"Adjective/Adverb","de":"Sıfat/Zarf","dt":"For the whole of the normal working week","e1":"Normal çalışma haftasının tamamı boyunca","e1t":"She has a full","e2":"time job.","e2t":"Tam zamanlı bir işi var."},{"w":"furnish","tr":"döşemek / donatmak / sağlamak","te":"Verb","tt":"Fiil","de":"To put furniture into a room or to provide","dt":"Bir odaya mobilya koymak veya sağlamak","e1":"They furnished the house with old furniture.","e1t":"Evi eski mobilyalarla döşediler.","e2":"The report furnishes all the necessary information.","e2t":"Rapor gerekli tüm bilgileri sağlıyor."},{"w":"fusion","tr":"birleşme / füzyon","te":"Noun","tt":"İsim","de":"The process of joining two or more things together","dt":"İki veya daha fazla şeyi birleştirme süreci","e1":"Nuclear fusion produces energy.","e1t":"Nükleer füzyon enerji üretir.","e2":"The restaurant serves a fusion of French and Japanese food.","e2t":"Restoran, Fransız ve Japon yemeklerinin bir birleşimini sunuyor."},{"w":"fuss","tr":"telaş / yaygara","te":"Noun/Verb","tt":"İsim/Fiil","de":"A show of unnecessary excitement or worry","dt":"Gereksiz bir heyecan veya endişe gösterisi","e1":"What is all the fuss about?","e1t":"Bu bütün yaygara ne hakkında?","e2":"Please don't make a fuss.","e2t":"Lütfen telaş yapma (meseleyi büyütme)."},{"w":"futile","tr":"beyhude / nafile / boşuna","te":"Adjective","tt":"Sıfat","de":"Having no effect or achieving nothing","dt":"Hiçbir etkisi olmayan veya hiçbir şey başaramayan","e1":"It was a futile attempt to save the company.","e1t":"Şirketi kurtarmak için nafile bir girişimdi.","e2":"Resistance is futile.","e2t":"Direniş beyhudedir (boşunadır)."},{"w":"gadget","tr":"alet / küçük cihaz","te":"Noun","tt":"İsim","de":"A small technological tool or machine","dt":"Küçük teknolojik araç veya makine","e1":"This kitchen gadget is very useful.","e1t":"Bu mutfak aleti çok kullanışlı.","e2":"He loves buying the latest gadgets.","e2t":"En son teknolojik aletleri almayı sever."},{"w":"gamble","tr":"kumar oynamak / risk almak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To risk money or to take a chance","dt":"Para riske atmak veya şansını denemek","e1":"He gambled all his money and lost.","e1t":"Bütün parasını kumarda kaybetti.","e2":"It was a gamble to start the business.","e2t":"İşi başlatmak bir riskti (kumardı)."},{"w":"gang","tr":"çete / grup","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of people who are often involved in crime","dt":"Genellikle suça karışan insan grubu","e1":"The local gang causes many problems.","e1t":"Yerel çete birçok soruna neden oluyor.","e2":"A gang of teenagers was hanging out.","e2t":"Bir genç grubu dışarıda takılıyordu."},{"w":"gardener","tr":"bahçıvan","te":"Noun","tt":"İsim","de":"A person who works in a garden","dt":"Bahçede çalışan kişi","e1":"We hired a gardener to look after the lawn.","e1t":"Çimlere bakması için bir bahçıvan tuttuk.","e2":"He is a very talented gardener.","e2t":"O çok yetenekli bir bahçıvandır."},{"w":"garment","tr":"giysi / kıyafet","te":"Noun","tt":"İsim","de":"A piece of clothing","dt":"Bir giysi parçası","e1":"This store sells high","e1t":"quality garments.","e2":"Bu mağaza yüksek kaliteli giysiler satıyor.","e2t":"Please hang your garments in the closet."},{"w":"gasp","tr":"nefesi kesilmek / soluk soluğa kalmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To breathe in suddenly because of surprise or pain","dt":"Sürpriz veya acı nedeniyle aniden nefes almak","e1":"She gasped in surprise.","e1t":"Şaşkınlıktan nefesi kesildi.","e2":"He gave a gasp of relief.","e2t":"Rahatlayarak derin bir soluk aldı."},{"w":"gauge","tr":"ölçmek / gösterge","te":"Verb/Noun","tt":"Fiil/İsim","de":"To measure or calculate something; a measuring tool","dt":"Bir şeyi ölçmek veya hesaplamak; ölçme aracı","e1":"It's difficult to gauge his reaction.","e1t":"Onun tepkisini ölçmek (tahmin etmek) zor.","e2":"Check the fuel gauge.","e2t":"Yakıt göstergesini kontrol et."},{"w":"gaze","tr":"dik dik bakmak / gözünü dikmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look at something for a long time","dt":"Bir şeye uzun süre bakmak","e1":"He gazed at the stars for hours.","e1t":"Saatlerce yıldızlara baktı.","e2":"She met his gaze.","e2t":"Onun bakışıyla (göz göze) geldi."},{"w":"gene","tr":"gen","te":"Noun","tt":"İsim","de":"A part of a cell that controls characteristics","dt":"Özellikleri kontrol eden hücre parçası","e1":"Blue eyes are in my genes.","e1t":"Mavi gözler benim genlerimde var.","e2":"Scientists are studying the human gene.","e2t":"Bilim insanları insan genini inceliyor."},{"w":"generosity","tr":"cömertlik","te":"Noun","tt":"İsim","de":"The quality of being kind and sharing","dt":"Nazik olma ve paylaşma özelliği","e1":"Thank you for your great generosity.","e1t":"Büyük cömertliğiniz için teşekkürler.","e2":"His generosity is known by everyone.","e2t":"Onun cömertliği herkes tarafından bilinir."},{"w":"genuinely","tr":"gerçekten / samimiyetle","te":"Adverb","tt":"Zarf","de":"Truly or honestly","dt":"Gerçekten veya dürüstçe","e1":"I am genuinely sorry.","e1t":"Gerçekten (samimiyetle) üzgünüm.","e2":"He is genuinely interested in art.","e2t":"Sanata gerçekten ilgi duyuyor."},{"w":"geographic","tr":"coğrafi","te":"Adjective","tt":"Sıfat","de":"Relating to geography","dt":"Coğrafya ile ilgili","e1":"The geographic location of Turkey is unique.","e1t":"Türkiye'nin coğrafi konumu benzersizdir.","e2":"We have some geographic data.","e2t":"Bazı coğrafi verilere sahibiz."},{"w":"giggle","tr":"kıkırdamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh in a silly or nervous way","dt":"Aptalca veya gergin bir şekilde gülmek","e1":"The kids started to giggle during the lesson.","e1t":"Çocuklar ders sırasında kıkırdamaya başladı.","e2":"She gave a little giggle.","e2t":"Hafifçe kıkırdadı."},{"w":"glance","tr":"göz atmak / hızlıca bakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look quickly at something","dt":"Bir şeye hızlıca bakmak","e1":"He glanced at his watch.","e1t":"Saatini kontrol etti (bir göz attı).","e2":"I took a quick glance at the headlines.","e2t":"Manşetlere hızlıca bir göz attım."},{"w":"glare","tr":"sert bakmak / göz kamaştırıcı ışık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look angrily or a very bright light","dt":"Öfkeyle bakmak veya çok parlak ışık","e1":"He glared at me in silence.","e1t":"Sessizlik içinde bana sertçe baktı.","e2":"The glare from the sun made it hard to see.","e2t":"Güneşten gelen göz kamaştırıcı ışık görmeyi zorlaştırdı."},{"w":"glassware","tr":"cam eşya","te":"Noun","tt":"İsim","de":"Objects made of glass","dt":"Camdan yapılmış nesneler","e1":"Be careful with the glassware.","e1t":"Cam eşyalara karşı dikkatli ol.","e2":"They sell beautiful glassware in that shop.","e2t":"Şu dükkanda güzel cam eşyalar satıyorlar."},{"w":"gloomy","tr":"kasvetli / karanlık / karamsar","te":"Adjective","tt":"Sıfat","de":"Dark or not hopeful","dt":"Karanlık veya umutsuz","e1":"It was a gloomy winter day.","e1t":"Kasvetli bir kış günüydü.","e2":"He has a gloomy outlook on the future.","e2t":"Geleceğe dair karamsar bir bakış açısı var."},{"w":"glorify","tr":"yüceltmek / övmek","te":"Verb","tt":"Fiil","de":"To praise or honor someone or something","dt":"Birini veya bir şeyi övmek veya onurlandırmak","e1":"The movie glorifies violence.","e1t":"Film şiddeti yüceltiyor.","e2":"They sing songs to glorify God.","e2t":"Tanrı'yı yüceltmek için şarkılar söylüyorlar."},{"w":"goddess","tr":"tanrıça","te":"Noun","tt":"İsim","de":"A female god","dt":"Kadın tanrı","e1":"Athena was the Greek goddess of wisdom.","e1t":"Athena, Yunan bilgelik tanrıçasıydı.","e2":"She was treated like a goddess.","e2t":"Ona bir tanrıça gibi davranıldı."},{"w":"good","tr":"natured","te":"iyi huylu / uysal","tt":"Adjective","de":"Sıfat","dt":"Naturally kind and friendly","e1":"Doğuştan nazik ve arkadaş canlısı","e1t":"He is a good","e2":"natured person.","e2t":"O iyi huylu biridir."},{"w":"gown","tr":"uzun resmi elbise / cübbe","te":"Noun","tt":"İsim","de":"A long formal dress or a special robe","dt":"Uzun resmi elbise veya özel bir cübbe","e1":"She wore a beautiful silk gown.","e1t":"Güzel bir ipek elbise giydi.","e2":"Graduation gowns are traditionally black.","e2t":"Mezuniyet cübbeleri geleneksel olarak siyahtır."},{"w":"graceful","tr":"zarif","te":"Adjective","tt":"Sıfat","de":"Moving in a smooth and attractive way","dt":"Pürüzsüz ve çekici bir şekilde hareket eden","e1":"The dancer was very graceful.","e1t":"Dansçı çok zarifti.","e2":"She has a graceful style.","e2t":"Zarif bir tarzı var."},{"w":"gratitude","tr":"minnettarlık / şükran","te":"Noun","tt":"İsim","de":"The feeling of being grateful and wanting to say thank you","dt":"Minnettar olma ve teşekkür etme isteği","e1":"I want to express my gratitude for your help.","e1t":"Yardımın için minnettarlığımı ifade etmek istiyorum.","e2":"He showed his gratitude by buying a gift.","e2t":"Hediye alarak şükranını gösterdi."},{"w":"grave","tr":"ciddi / mezar","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Very serious or a place where a dead person is buried","dt":"Çok ciddi veya ölünün gömüldüğü yer","e1":"The situation is grave.","e1t":"Durum ciddidir.","e2":"He visited his father's grave.","e2t":"Babasının mezarını ziyaret etti."},{"w":"gravel","tr":"çakıl","te":"Noun","tt":"İsim","de":"Small stones used for paths or roads","dt":"Yollar veya yollar için kullanılan küçük taşlar","e1":"The sound of tires on gravel.","e1t":"Çakıl üzerindeki lastiklerin sesi.","e2":"The path is covered with gravel.","e2t":"Patika çakılla kaplı."},{"w":"graze","tr":"otlamak / sıyırmak (yara)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To eat grass or to touch something lightly","dt":"Ot yemek veya bir şeye hafifçe dokunmak","e1":"The cows were grazing in the field.","e1t":"İnekler tarlada otluyorlardı.","e2":"The bullet grazed his arm.","e2t":"Kurşun kolunu sıyırdı."},{"w":"greenhouse","tr":"sera","te":"Noun","tt":"İsim","de":"A glass building used for growing plants","dt":"Bitki yetiştirmek için kullanılan cam bina","e1":"We grow tomatoes in the greenhouse.","e1t":"Serada domates yetiştiriyoruz.","e2":"The greenhouse effect causes global warming.","e2t":"Sera etkisi küresel ısınmaya neden olur."},{"w":"guidance","tr":"rehberlik / yol gösterme","te":"Noun","tt":"İsim","de":"Help or advice given to someone","dt":"Birine verilen yardım veya tavsiye","e1":"I need some guidance on this career choice.","e1t":"Bu kariyer seçimi konusunda biraz rehberliğe ihtiyacım var.","e2":"Under the guidance of his teacher.","e2t":"Öğretmeninin rehberliği altında."},{"w":"gullible","tr":"saf / safdil / kandırılabilir","te":"Adjective","tt":"Sıfat","de":"Easily deceived or tricked","dt":"Kolayca aldatılabilen veya kandırılabilen","e1":"He is so gullible that he believes everything.","e1t":"O kadar saf ki her şeye inanıyor.","e2":"Don't be so gullible.","e2t":"Bu kadar saf olma."},{"w":"gulp","tr":"yutmak / bir dikişte içmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To swallow food or drink quickly","dt":"Yiyecek veya içeceği hızla yutmak","e1":"He gulped down his coffee.","e1t":"Kahvesini bir dikişte içti (yuttu).","e2":"She took a big gulp of air.","e2t":"Derin bir nefes aldı."},{"w":"gut","tr":"bağırsak / cesaret (argo)","te":"Noun/Verb/Adjective","tt":"The digestive tube or courage","de":"Sindirim borusu veya cesaret","dt":"I have a gut feeling about this.","e1":"Bu konuda içsel bir hissim (bağırsak hissi) var.","e1t":"It takes guts to speak the truth.","e2":"Doğruyu söylemek cesaret ister.","e2t":""},{"w":"hail","tr":"dolu (yağış) / selamlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Small balls of ice falling like rain; to greet","dt":"Yağmur gibi düşen küçük buz topları; selamlamak","e1":"The car was damaged by hail.","e1t":"Araba dolu yüzünden zarar gördü.","e2":"They hailed him as a hero.","e2t":"Onu bir kahraman olarak selamladılar."},{"w":"halfway","tr":"yarı yolda","te":"Adverb/Adjective","tt":"In the middle of something","de":"Bir şeyin ortasında","dt":"We are halfway there.","e1":"Yarı yola vardık.","e1t":"I am halfway through the book.","e2":"Kitabın yarısındayım.","e2t":""},{"w":"halt","tr":"durdurmak / durma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop moving or happening","dt":"Hareket etmeyi veya gerçekleşmeyi durdurmak","e1":"The strike halted production.","e1t":"Grev üretimi durdurdu.","e2":"The car came to a sudden halt.","e2t":"Araba ani bir duruş yaptı."},{"w":"hammer","tr":"çekiç / çekiçle vurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool with a metal head for hitting nails","dt":"Çivi çakmak için metal başlı alet","e1":"Use a hammer to fix the picture.","e1t":"Resmi sabitlemek için çekiç kullan.","e2":"He hammered the nail into the wall.","e2t":"Çiviyi duvara çaktı."},{"w":"hamper","tr":"engellemek / sepet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To prevent someone from moving or acting freely","dt":"Birinin özgürce hareket etmesini veya davranmasını engellemek","e1":"Bad weather hampered the rescue efforts.","e1t":"Kötü hava kurtarma çalışmalarını engelledi.","e2":"A laundry hamper.","e2t":"Çamaşır sepeti."},{"w":"handout","tr":"dağıtılan belge / sadaka","te":"Noun","tt":"İsim","de":"Information printed on paper to be given to people","dt":"İnsanlara verilmek üzere kağıda basılmış bilgi","e1":"Please look at the handout I gave you.","e1t":"Lütfen size verdiğim dağıtılan belgeye bakın.","e2":"They don't want a handout; they want jobs.","e2t":"Sadaka istemiyorlar; iş istiyorlar."},{"w":"handy","tr":"kullanışlı / el altında","te":"Adjective","tt":"Sıfat","de":"Useful or near and easy to reach","dt":"Yararlı veya yakın ve ulaşılması kolay","e1":"This tool will come in handy.","e1t":"Bu alet işe yarayacak (el altında olması iyi olacak).","e2":"Keep a torch handy.","e2t":"Bir el fenerini el altında tut."},{"w":"hang out","tr":"takılmak / vakit geçirmek","te":"Verb","tt":"Fiil","de":"To spend a lot of time in a place or with someone","dt":"Bir yerde veya biriyle çok zaman geçirmek","e1":"Where do you usually hang out?","e1t":"Genellikle nerede takılırsın?","e2":"I like hanging out with my friends.","e2t":"Arkadaşlarımla takılmayı severim."},{"w":"happening","tr":"olay / gelişme","te":"Noun","tt":"İsim","de":"Something that happens","dt":"Gerçekleşen şey","e1":"It was a strange happening.","e1t":"Garip bir olaydı.","e2":"There are many interesting happenings in the city.","e2t":"Şehirde birçok ilginç gelişme (olay) var."},{"w":"harass","tr":"taciz etmek / rahatsız etmek","te":"Verb","tt":"Fiil","de":"To continue to annoy or upset someone","dt":"Birini rahatsız etmeye veya üzmeye devam etmek","e1":"He was accused of harassing his colleagues.","e1t":"Meslektaşlarını taciz etmekle suçlandı.","e2":"Stop harassing me!","e2t":"Beni rahatsız etmeyi bırak!"},{"w":"hardship","tr":"zorluk / güçlük / darlık","te":"Noun","tt":"İsim","de":"A condition of life that is difficult","dt":"Zor olan yaşam koşulu","e1":"They suffered great hardship during the war.","e1t":"Savaş sırasında büyük zorluk çektiler.","e2":"Financial hardship is common in this area.","e2t":"Bu bölgede maddi zorluk yaygındır."},{"w":"harmless","tr":"zararsız","te":"Adjective","tt":"Sıfat","de":"Not causing any harm","dt":"Hiçbir zarara neden olmayan","e1":"It was a harmless joke.","e1t":"Zararsız bir şakaydı.","e2":"This snake is harmless.","e2t":"Bu yılan zararsızdır."},{"w":"harness","tr":"faydalanmak / dizginlemek / koşum takımı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To control and use energy; equipment for a horse","dt":"Enerjiyi kontrol etmek ve kullanmak; at ekipmanı","e1":"We should harness solar energy.","e1t":"Güneş enerjisinden faydalanmalıyız (onu dizginlemeliyiz).","e2":"A safety harness.","e2t":"Güvenlik kemeri (koşum)."},{"w":"haste","tr":"acele","te":"Noun","tt":"İsim","de":"Speed in doing something; hurry","dt":"Bir şeyi yapmadaki hız; acele","e1":"Haste makes waste.","e1t":"Acele işe şeytan karışır (Acele kayıp getirir).","e2":"He left in great haste.","e2t":"Büyük bir aceleyle ayrıldı."},{"w":"hasty","tr":"aceleci / çalakalem","te":"Adjective","tt":"Sıfat","de":"Done very quickly, usually too quickly","dt":"Çok hızlı yapılan, genellikle fazla hızlı","e1":"Don't make a hasty decision.","e1t":"Aceleci bir karar verme.","e2":"It was a hasty retreat.","e2t":"Acele bir geri çekilmeydi."},{"w":"hatch","tr":"yumurtadan çıkmak / ambar kapağı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come out of an egg","dt":"Yumurtadan çıkmak","e1":"The chicks hatched yesterday.","e1t":"Civcivler dün yumurtadan çıktı.","e2":"He opened the hatch of the ship.","e2t":"Geminin ambar kapağını açtı."},{"w":"hatred","tr":"nefret","te":"Noun","tt":"İsim","de":"A very strong feeling of dislike","dt":"Çok güçlü bir hoşlanmama duygusu","e1":"He looked at me with pure hatred.","e1t":"Bana saf nefretle baktı.","e2":"We must overcome racial hatred.","e2t":"Irksal nefretin üstesinden gelmeliyiz."},{"w":"haunt","tr":"musallat olmak / uğrak yeri","te":"Verb/Noun","tt":"Fiil/İsim","de":"To appear frequently as a ghost; to visit often","dt":"Hayalet olarak sıkça görünmek; bir yere sıkça uğramak","e1":"The memory of the accident haunts him.","e1t":"Kaza hatırası ona musallat oluyor (zihninden çıkmıyor).","e2":"This cafe is one of my favorite haunts.","e2t":"Bu kafe en sevdiğim uğrak yerlerimden biridir."},{"w":"hazard","tr":"tehlike / risk","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that is dangerous","dt":"Tehlikeli olan bir şey","e1":"Icy roads are a hazard to drivers.","e1t":"Buzlu yollar sürücüler için bir tehlikedir.","e2":"Health hazards of smoking.","e2t":"Sigara içmenin sağlık riskleri."},{"w":"healthcare","tr":"sağlık hizmetleri","te":"Noun","tt":"İsim","de":"The providing of medical services","dt":"Tıbbi hizmetlerin sağlanması","e1":"The government is improving healthcare.","e1t":"Hükümet sağlık hizmetlerini iyileştiriyor.","e2":"Healthcare costs are rising.","e2t":"Sağlık hizmetleri maliyetleri artıyor."},{"w":"heap","tr":"yığın / küme","te":"Noun/Verb","tt":"İsim/Fiil","de":"An untidy pile of things","dt":"Şeylerin düzensiz yığını","e1":"There is a heap of clothes on the floor.","e1t":"Yerde bir kıyafet yığını var.","e2":"He heaped more wood on the fire.","e2t":"Ateşe daha fazla odun yığdı."},{"w":"heartbeat","tr":"kalp atışı","te":"Noun","tt":"İsim","de":"The regular movement or sound of the heart","dt":"Kalbin düzenli hareketi veya sesi","e1":"His heartbeat was fast and irregular.","e1t":"Kalp atışı hızlı ve düzensizdi.","e2":"I could feel my heartbeat.","e2t":"Kalp atışımı hissedebiliyordum."},{"w":"hedge","tr":"çit (bitkiden) / önlem almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of bushes or a way to limit loss","dt":"Çalı sırası veya kaybı sınırlama yolu","e1":"He trimmed the garden hedge.","e1t":"Bahçe çitini (çalıları) budadı.","e2":"He hedged his bets by investing in gold.","e2t":"Altına yatırım yaparak risklerini sınırladı (önlemini aldı)."},{"w":"herd","tr":"sürü / gütmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large group of animals","dt":"Büyük bir hayvan grubu","e1":"A herd of cows was crossing the road.","e1t":"Bir inek sürüsü yolu geçiyordu.","e2":"He herded the sheep into the barn.","e2t":"Koyunları ahıra güttü."},{"w":"hidden","tr":"gizli / saklı","te":"Adjective","tt":"Sıfat","de":"Put out of sight; difficult to find","dt":"Görüş alanının dışında; bulunması zor","e1":"There is a hidden door behind the bookshelf.","e1t":"Kitaplığın arkasında gizli bir kapı var.","e2":"He has a hidden talent for painting.","e2t":"Resim yapmaya karşı gizli bir yeteneği var."},{"w":"hint","tr":"ipucu / ima etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of practical information or a suggestion","dt":"Küçük pratik bilgi veya ima","e1":"He gave me a hint about the answer.","e1t":"Cevapla ilgili bana bir ipucu verdi.","e2":"She hinted that she might leave.","e2t":"Ayrılacağına dair imada bulundu."},{"w":"historian","tr":"tarihçi","te":"Noun","tt":"İsim","de":"A person who studies or writes about history","dt":"Tarih çalışan veya tarih hakkında yazan kişi","e1":"He is a famous military historian.","e1t":"O, ünlü bir askeri tarihçidir.","e2":"Historians agree on the importance of this event.","e2t":"Tarihçiler bu olayın önemi konusunda hemfikir."},{"w":"historic","tr":"tarihi (önemli)","te":"Adjective","tt":"Sıfat","de":"Important or likely to be important in history","dt":"Tarihte önemli olan veya olması muhtemel olan","e1":"This is a historic moment for our country.","e1t":"Bu, ülkemiz için tarihi bir andır.","e2":"A historic meeting between the two leaders.","e2t":"İki lider arasında tarihi bir görüşme."},{"w":"historical","tr":"tarihî (geçmişle ilgili)","te":"Adjective","tt":"Sıfat","de":"Connected with studying or representing things from the past","dt":"Geçmişteki şeyleri incelemekle veya temsil etmekle ilgili","e1":"I love reading historical novels.","e1t":"Tarihî romanlar okumayı severim.","e2":"The building has great historical value.","e2t":"Binanın büyük tarihî değeri var."},{"w":"hit","tr":"vurmak / çarpmak / başarı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To touch something with force; a success","dt":"Bir şeye güçle dokunmak; bir başarı","e1":"He hit the ball over the fence.","e1t":"Topa vurup çitlerin üzerinden aşırdı.","e2":"The song was a big hit in the 90s.","e2t":"Şarkı 90'larda büyük bir başarıydı (hit oldu)."},{"w":"hollow","tr":"içi boş / oyuk","te":"Adjective/Noun/Verb","tt":"Having an empty space inside","de":"İçinde boş bir alan olan","dt":"Bamboo stems are hollow.","e1":"Bambu saplarının içi boştur.","e1t":"He hid the money in a hollow tree.","e2":"Parayı oyuk bir ağaca sakladı.","e2t":""},{"w":"holy","tr":"kutsal","te":"Adjective","tt":"Sıfat","de":"Related to a god or religion","dt":"Bir tanrı veya din ile ilgili","e1":"Jerusalem is a holy city.","e1t":"Kudüs kutsal bir şehirdir.","e2":"The Holy Bible.","e2t":"Kutsal Kitap."},{"w":"honesty","tr":"dürüstlük","te":"Noun","tt":"İsim","de":"The quality of being honest","dt":"Dürüst olma özelliği","e1":"I appreciate your honesty.","e1t":"Dürüstlüğünü takdir ediyorum.","e2":"Honesty is the best policy.","e2t":"Dürüstlük en iyi politikadır."},{"w":"honor / honour","tr":"onur / şeref / onurlandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great respect or to show great respect","dt":"Büyük saygı veya büyük saygı göstermek","e1":"It is an honor to meet you.","e1t":"Sizinle tanışmak bir onurdur.","e2":"They honored the war veterans.","e2t":"Savaş gazilerini onurlandırdılar."},{"w":"honorary","tr":"fahri / onursal","te":"Adjective","tt":"Sıfat","de":"Given as an honor without the usual requirements","dt":"Olağan gereklilikler olmadan bir onur olarak verilen","e1":"He received an honorary degree from the university.","e1t":"Üniversiteden fahri bir derece aldı.","e2":"He is the honorary president of the club.","e2t":"Kulübün onursal başkanıdır."},{"w":"hook","tr":"kanca / asmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A curved tool for catching or hanging things","dt":"Bir şeyleri yakalamak veya asmak için kavisli araç","e1":"Hang your coat on the hook.","e1t":"Montunu kancaya as.","e2":"He caught a huge fish on his hook.","e2t":"Kancasına kocaman bir balık takıldı."},{"w":"hopeful","tr":"umutlu","te":"Adjective","tt":"Sıfat","de":"Feeling or inspiring hope","dt":"Umut hisseden veya ilham veren","e1":"I am hopeful that we will win.","e1t":"Kazanacağımızdan umutluyum.","e2":"He gave me a hopeful smile.","e2t":"Bana umutlu bir gülümseme attı."},{"w":"hopeless","tr":"umutsuz","te":"Adjective","tt":"Sıfat","de":"Without hope","dt":"Umudu olmayan","e1":"The situation is hopeless.","e1t":"Durum umutsuzdur.","e2":"I am hopeless at math.","e2t":"Matematik konusunda ümitsiz vakayım (çok kötüyüm)."},{"w":"horizon","tr":"ufuk","te":"Noun","tt":"İsim","de":"The line where the earth and sky seem to meet","dt":"Yer ve göğün birleştiği gibi görünen çizgi","e1":"The sun disappeared below the horizon.","e1t":"Güneş ufkun altında kayboldu.","e2":"Traveling broadens your horizons.","e2t":"Seyahat etmek ufkunuzu genişletir."},{"w":"horizontal","tr":"yatay","te":"Adjective","tt":"Sıfat","de":"Parallel to the ground","dt":"Yere paralel","e1":"Draw a horizontal line.","e1t":"Yatay bir çizgi çek.","e2":"Keep the surface horizontal.","e2t":"Yüzeyi yatay tut."},{"w":"horn","tr":"boynuz / korna","te":"Noun","tt":"İsim","de":"A hard part on an animal's head or a warning sound","dt":"Hayvanın başındaki sert parça veya uyarı sesi","e1":"A bull has two horns.","e1t":"Bir boğanın iki boynuzu vardır.","e2":"He blew his car horn.","e2t":"Arabasının kornasına bastı."},{"w":"horrible","tr":"berbat / korkunç","te":"Adjective","tt":"Sıfat","de":"Very unpleasant or frightening","dt":"Çok hoş olmayan veya korkutucu","e1":"The weather was horrible.","e1t":"Hava berbattı.","e2":"I had a horrible dream.","e2t":"Korkunç bir rüya gördüm."},{"w":"horror","tr":"korku / dehşet","te":"Noun","tt":"İsim","de":"A feeling of great shock or fear","dt":"Büyük bir şok veya korku hissi","e1":"I watched a horror movie last night.","e1t":"Dün gece bir korku filmi izledim.","e2":"She screamed in horror.","e2t":"Dehşet içinde çığlık attı."},{"w":"horseman","tr":"atlı / süvari","te":"Noun","tt":"İsim","de":"A person who rides a horse","dt":"At binen kişi","e1":"He is a skilled horseman.","e1t":"O yetenekli bir atlıdır.","e2":"The horseman disappeared into the woods.","e2t":"Atlı ormanda gözden kayboldu."},{"w":"hospitality","tr":"misafirperverlik","te":"Noun","tt":"İsim","de":"Kind and generous treatment of guests","dt":"Misafirlere karşı nazik ve cömert davranış","e1":"Thank you for your wonderful hospitality.","e1t":"Harika misafirperverliğiniz için teşekkürler.","e2":"Turkish people are known for their hospitality.","e2t":"Türk insanı misafirperverliğiyle tanınır."},{"w":"hostile","tr":"düşmanca / saldırgan","te":"Adjective","tt":"Sıfat","de":"Unfriendly or showing dislike","dt":"Arkadaşça olmayan veya hoşnutsuzluk gösteren","e1":"The crowd was hostile toward the speaker.","e1t":"Kalabalık konuşmacıya karşı düşmanca bir tutum içindeydi.","e2":"A hostile environment.","e2t":"Düşmanca bir ortam."},{"w":"household","tr":"ev halkı / eve ait","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A group of people living together in a house","dt":"Bir evde birlikte yaşayan insan grubu","e1":"He grew up in a busy household.","e1t":"Hareketli bir ev halkı içinde büyüdü.","e2":"Household chores (cleaning, cooking).","e2t":"Ev işleri."},{"w":"housing","tr":"barınma / konut","te":"Noun","tt":"İsim","de":"Buildings for people to live in","dt":"İnsanların yaşaması için binalar","e1":"There is a shortage of affordable housing.","e1t":"Uygun fiyatlı konut sıkıntısı var.","e2":"The government is investing in new housing projects.","e2t":"Hükümet yeni konut projelerine yatırım yapıyor."},{"w":"hover","tr":"havada durmak / dolanmak","te":"Verb","tt":"Fiil","de":"To stay in one place in the air","dt":"Havada bir yerde durmak","e1":"The helicopter hovered over the building.","e1t":"Helikopter binanın üzerinde havada asılı kaldı.","e2":"A doubt still hovers in my mind.","e2t":"Zihnimde hala bir şüphe dolanıyor."},{"w":"hug","tr":"sarılmak / kucaklaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hold someone close in your arms","dt":"Birini kollarının arasında yakından tutmak","e1":"Give me a hug.","e1t":"Bana bir sarıl.","e2":"They hugged each other before saying goodbye.","e2t":"Vedalaşmadan önce birbirlerine sarıldılar."},{"w":"humane","tr":"insancıl / merhametli","te":"Adjective","tt":"Sıfat","de":"Showing kindness and care","dt":"Nezaket ve ilgi gösteren","e1":"We must ensure the humane treatment of animals.","e1t":"Hayvanlara insancıl davranılmasını sağlamalıyız.","e2":"He is a very humane person.","e2t":"O çok insancıl biridir."},{"w":"humanity","tr":"insanlık","te":"Noun","tt":"İsim","de":"All people as a group; or human nature","dt":"Bir grup olarak tüm insanlar; veya insan doğası","e1":"This is a crime against humanity.","e1t":"Bu, insanlığa karşı işlenmiş bir suçtur.","e2":"He has lost his faith in humanity.","e2t":"İnsanlığa olan inancını yitirdi."},{"w":"humble","tr":"mütevazı / alçakgönüllü","te":"Adjective/Verb","tt":"Not proud or thinking you are better than others","de":"Gururlu olmayan veya diğerlerinden daha iyi olduğunu düşünmeyen","dt":"He is a very humble man despite his success.","e1":"Başarısına rağmen çok mütevazı bir adamdır.","e1t":"In my humble opinion.","e2":"Benim mütevazı görüşüme göre.","e2t":""},{"w":"humidity","tr":"nem","te":"Noun","tt":"İsim","de":"The amount of water in the air","dt":"Havadaki su miktarı","e1":"The humidity is very high today.","e1t":"Bugün nem çok yüksek.","e2":"High humidity makes the heat feel worse.","e2t":"Yüksek nem ısıyı daha kötü hissettirir."},{"w":"humorous","tr":"mizahi / komik","te":"Adjective","tt":"Sıfat","de":"Funny or making you laugh","dt":"Komik veya sizi güldüren","e1":"He told a humorous story.","e1t":"Mizahi bir hikaye anlattı.","e2":"She has a humorous look at life.","e2t":"Hayata mizahi bir bakışı var."},{"w":"hunger","tr":"açlık","te":"Noun","tt":"İsim","de":"The feeling of wanting food","dt":"Yemek isteme hissi","e1":"Many people die of hunger every day.","e1t":"Her gün birçok kişi açlıktan ölüyor.","e2":"They went on a hunger strike.","e2t":"Açlık grevine gittiler."},{"w":"hurricane","tr":"kasırga","te":"Noun","tt":"İsim","de":"A violent storm with very strong winds","dt":"Çok güçlü rüzgarları olan şiddetli fırtına","e1":"The hurricane caused massive damage.","e1t":"Kasırga büyük hasara yol açtı.","e2":"Hurricanes are common in the Atlantic.","e2t":"Atlas Okyanusu'nda kasırgalar yaygındır."},{"w":"hurtful","tr":"kırıcı / incitici","te":"Adjective","tt":"Sıfat","de":"Causing emotional pain","dt":"Duygusal acıya neden olan","e1":"She made some hurtful comments.","e1t":"Bazı kırıcı yorumlar yaptı.","e2":"I didn't mean to be hurtful.","e2t":"Kırıcı olmak istememiştim."},{"w":"hygiene","tr":"hijyen / temizlik","te":"Noun","tt":"İsim","de":"Keeping yourself and your surroundings clean","dt":"Kendini ve çevreni temiz tutma","e1":"Dental hygiene is important.","e1t":"Diş hijyeni önemlidir.","e2":"Poor hygiene can lead to infection.","e2t":"Kötü hijyen enfeksiyona yol açabilir."},{"w":"hypothesis","tr":"hipotez / varsayım","te":"Noun","tt":"İsim","de":"An idea or theory that is not yet proven","dt":"Henüz kanıtlanmamış fikir veya teori","e1":"Our results support the original hypothesis.","e1t":"Sonuçlarımız orijinal hipotezi destekliyor.","e2":"Scientists are testing a new hypothesis.","e2t":"Bilim insanları yeni bir hipotezi test ediyorlar."},{"w":"hypothetical","tr":"varsayımsal","te":"Adjective","tt":"Sıfat","de":"Based on a situation that is not real","dt":"Gerçek olmayan bir duruma dayanan","e1":"Let's consider a hypothetical situation.","e1t":"Varsayımsal bir durumu değerlendirelim.","e2":"This is just a hypothetical question.","e2t":"Bu sadece varsayımsal bir sorudur."},{"w":"icon","tr":"ikon / simge","te":"Noun","tt":"İsim","de":"A symbol or a very famous person","dt":"Bir sembol veya çok ünlü bir kişi","e1":"Click on the printer icon.","e1t":"Yazıcı ikonuna (simgesine) tıkla.","e2":"Elvis Presley is a cultural icon.","e2t":"Elvis Presley kültürel bir ikondur."},{"w":"identical","tr":"tıpatıp aynı","te":"Adjective","tt":"Sıfat","de":"Exactly the same","dt":"Tamamen aynı","e1":"The two pictures are almost identical.","e1t":"İki resim neredeyse tıpatıp aynı.","e2":"They are identical twins.","e2t":"Onlar tek yumurta (özdeş) ikizleridir."},{"w":"identity","tr":"kimlik","te":"Noun","tt":"İsim","de":"Who a person is","dt":"Bir kişinin kim olduğu","e1":"The police are trying to establish his identity.","e1t":"Polis onun kimliğini belirlemeye çalışıyor.","e2":"She has a strong sense of national identity.","e2t":"Güçlü bir ulusal kimlik duygusu var."},{"w":"idle","tr":"boş / işsiz / aylak","te":"Adjective/Verb","tt":"Not working or being used","de":"Çalışmayan veya kullanılmayan","dt":"The machines have been idle for weeks.","e1":"Makineler haftalardır boşta (çalışmıyor).","e1t":"He is an idle student.","e2":"O tembel (aylak) bir öğrencidir.","e2t":""},{"w":"idol","tr":"idol / put","te":"Noun","tt":"İsim","de":"A person who is greatly admired","dt":"Çok büyük hayranlık duyulan kişi","e1":"He was a teenage idol in the 60s.","e1t":"60'larda bir gençlik idolüydü.","e2":"Pop idols have many fans.","e2t":"Pop idollerinin birçok hayranı vardır."},{"w":"ignore","tr":"görmezden gelmek / yok saymak","te":"Verb","tt":"Fiil","de":"To pay no attention to something","dt":"Bir şeye dikkat etmemek","e1":"Don't ignore his advice.","e1t":"Onun tavsiyesini görmezden gelme.","e2":"She ignored my question.","e2t":"Sorumu yok saydı."},{"w":"illegal","tr":"yasa dışı","te":"Adjective","tt":"Sıfat","de":"Not allowed by law","dt":"Yasalarca izin verilmeyen","e1":"It is illegal to drive without a license.","e1t":"Ehliyetsiz araba sürmek yasa dışıdır.","e2":"They were involved in illegal activities.","e2t":"Yasa dışı faaliyetlere karışmışlardı."},{"w":"illogical","tr":"mantıksız","te":"Adjective","tt":"Sıfat","de":"Not based on clear or sensible reasons","dt":"Net veya mantıklı nedenlere dayanmayan","e1":"Your argument is completely illogical.","e1t":"Savunman tamamen mantıksız.","e2":"It was an illogical decision.","e2t":"Mantıksız bir karardı."},{"w":"illustrate","tr":"örneklemek / resimlemek","te":"Verb","tt":"Fiil","de":"To explain with examples or to draw pictures for a book","dt":"Örneklerle açıklamak veya bir kitap için resimler çizmek","e1":"Let me illustrate my point with an example.","e1t":"Durumumu bir örnekle açıklayayım (örnekleyeyim).","e2":"He illustrated many children's books.","e2t":"Birçok çocuk kitabını resimledi."},{"w":"illustration","tr":"illüstrasyon / örnekleme","te":"Noun","tt":"İsim","de":"A picture in a book or an example that explains something","dt":"Bir kitaptaki resim veya bir şeyi açıklayan örnek","e1":"Look at the illustration on page 20.","e1t":"20. sayfadaki illüstrasyona (resme) bakın.","e2":"This story is a good illustration of his character.","e2t":"Bu hikaye onun karakterinin iyi bir örneğidir (göstergesidir)."},{"w":"image","tr":"görüntü / imaj","te":"Noun","tt":"İsim","de":"A picture or the opinion people have of someone","dt":"Bir resim veya insanların biri hakkındaki düşüncesi","e1":"The telescope produces a clear image.","e1t":"Teleskop net bir görüntü üretiyor.","e2":"He is trying to improve his public image.","e2t":"Toplumsal imajını geliştirmeye çalışıyor."},{"w":"imaginary","tr":"hayali","te":"Adjective","tt":"Sıfat","de":"Not real; existing only in the mind","dt":"Gerçek olmayan; sadece zihinde var olan","e1":"The child has an imaginary friend.","e1t":"Çocuğun hayali bir arkadaşı var.","e2":"All the characters in this book are imaginary.","e2t":"Bu kitaptaki tüm karakterler hayalidir."},{"w":"imagination","tr":"hayal gücü","te":"Noun","tt":"İsim","de":"The ability to form mental pictures or new ideas","dt":"Zihinsel resimler veya yeni fikirler oluşturma yeteneği","e1":"You have a very vivid imagination.","e1t":"Çok canlı bir hayal gücün var.","e2":"It takes imagination to write a good story.","e2t":"İyi bir hikaye yazmak hayal gücü gerektirir."},{"w":"imitate","tr":"taklit etmek","te":"Verb","tt":"Fiil","de":"To copy someone's behavior or appearance","dt":"Birinin davranışını veya görünüşünü kopyalamak","e1":"He can imitate the voices of famous people.","e1t":"Ünlü insanların seslerini taklit edebilir.","e2":"Children often imitate their parents.","e2t":"Çocuklar sık sık ebeveynlerini taklit ederler."},{"w":"immense","tr":"çok büyük / muazzam","te":"Adjective","tt":"Sıfat","de":"Extremely large in size or degree","dt":"Boyut veya derece olarak aşırı büyük","e1":"The project was an immense success.","e1t":"Proje muazzam bir başarıydı.","e2":"They are under immense pressure.","e2t":"Muazzam baskı altındalar."},{"w":"immerse","tr":"daldırmak / kaptırmak","te":"Verb","tt":"Fiil","de":"To put into a liquid or to become completely involved","dt":"Bir sıvıya sokmak veya bir şeye tamamen dahil/meşgul olmak","e1":"Immerse the cloth in boiling water.","e1t":"Bezi kaynar suya daldırın.","e2":"He immersed himself in his work.","e2t":"Kendini işine kaptırdı."},{"w":"immigration","tr":"göç","te":"Noun","tt":"İsim","de":"The act of someone coming to live in a different country","dt":"Birinin farklı bir ülkede yaşamak için gelme eylemi","e1":"There are strict laws regarding immigration.","e1t":"Göçle ilgili katı yasalar vardır.","e2":"He works for the immigration department.","e2t":"Göç dairesinde çalışıyor."},{"w":"impair","tr":"zayıflatmak / bozmak","te":"Verb","tt":"Fiil","de":"To spoil or weaken something","dt":"Bir şeyi bozmak veya zayıflatmak","e1":"Lack of sleep can impair your judgment.","e1t":"Uykusuzluk muhakeme yeteneğinizi bozabilir.","e2":"His hearing was impaired by the accident.","e2t":"İşitmesi kaza nedeniyle zayıfladı (hasar gördü)."},{"w":"impart","tr":"aktarmak / vermek","te":"Verb","tt":"Fiil","de":"To give a feeling or quality to something; to pass on information","dt":"Bir şeye bir duygu veya özellik vermek; bilgiyi aktarmak","e1":"A teacher's job is to impart knowledge.","e1t":"Bir öğretmenin işi bilgiyi aktarmaktır.","e2":"The curtains impart a feeling of warmth to the room.","e2t":"Perdeler odaya bir sıcaklık hissi veriyor."},{"w":"imperative","tr":"zorunlu / acil","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Extremely important or urgent","dt":"Son derece önemli veya acil","e1":"It is imperative that you leave now.","e1t":"Şimdi ayrılman zorunludur.","e2":"Safety is a business imperative.","e2t":"Güvenlik bir iş zorunluluğudur."},{"w":"implement","tr":"uygulamak / yerine getirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To start using a plan or system","dt":"Bir planı veya sistemi kullanmaya başlamak","e1":"We need to implement the new rules immediately.","e1t":"Yeni kuralları derhal uygulamalıyız.","e2":"The government promised to implement the changes.","e2t":"Hükümet değişiklikleri yerine getirme sözü verdi."},{"w":"implication","tr":"ima / olası sonuç","te":"Noun","tt":"İsim","de":"A suggested meaning or a possible effect","dt":"Önerilen bir anlam veya olası bir etki","e1":"I didn't like the implication of his comment.","e1t":"Onun yorumunun imasını beğenmedim.","e2":"What are the financial implications of this choice?","e2t":"Bu seçimin finansal sonuçları (etkileri) nelerdir?"},{"w":"imply","tr":"ima etmek","te":"Verb","tt":"Fiil","de":"To suggest something without saying it directly","dt":"Bir şeyi doğrudan söylemeden önermek/kastetmek","e1":"Are you implying that I am lying?","e1t":"Yalan söylediğimi mi ima ediyorsun?","e2":"Silence does not always imply agreement.","e2t":"Sessizlik her zaman onay anlamına gelmez (onay ima etmez)."},{"w":"import","tr":"ithal etmek / ithalat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To buy goods from another country","dt":"Başka bir ülkeden mal satın almak","e1":"Turkey imports oil from other countries.","e1t":"Türkiye diğer ülkelerden petrol ithal eder.","e2":"This is an imported car.","e2t":"Bu ithal bir arabadır."},{"w":"impose","tr":"dayatmak / zorla kabul ettirmek","te":"Verb","tt":"Fiil","de":"To officially force a rule or tax; to put a burden","dt":"Resmi olarak bir kuralı veya vergiyi zorlamak; yük bindirmek","e1":"The government imposed a new tax on cigarettes.","e1t":"Hükümet sigaralara yeni bir vergi koydu (dayattı).","e2":"I don't want to impose my views on you.","e2t":"Görüşlerimi size dayatmak istemiyorum."},{"w":"impress","tr":"etkilemek","te":"Verb","tt":"Fiil","de":"To make someone admire or respect you","dt":"Birinin size hayran kalmasını veya saygı duymasını sağlamak","e1":"I was deeply impressed by his performance.","e1t":"Onun performansından derinden etkilendim.","e2":"He tried to impress the manager.","e2t":"Müdürü etkilemeye çalıştı."},{"w":"impressive","tr":"etkileyici","te":"Adjective","tt":"Sıfat","de":"Making a strong positive impact","dt":"Güçlü ve olumlu bir etki bırakan","e1":"The view from the top is impressive.","e1t":"Tepeden manzara etkileyicidir.","e2":"He gave an impressive speech.","e2t":"Etkileyici bir konuşma yaptı."},{"w":"imprison","tr":"hapsetmek","te":"Verb","tt":"Fiil","de":"To put someone in prison","dt":"Birini hapse atmak","e1":"He was imprisoned for five years.","e1t":"Beş yıl hapsedildi.","e2":"They were imprisoned for their political views.","e2t":"Siyasi görüşleri nedeniyle hapsedildiler."},{"w":"improvement","tr":"gelişme / iyileşme","te":"Noun","tt":"İsim","de":"The process of getting better","dt":"Daha iyi hale gelme süreci","e1":"There is a big improvement in your English.","e1t":"İngilizcende büyük bir gelişme var.","e2":"We need to make some improvements to the house.","e2t":"Evde bazı iyileştirmeler yapmamız gerekiyor."},{"w":"impulse","tr":"dürtü / ani istek","te":"Noun","tt":"İsim","de":"A sudden strong wish to do something","dt":"Bir şeyi yapmak için duyulan ani ve güçlü istek","e1":"I bought this coat on impulse.","e1t":"Bu paltoyu bir dürtüyle (düşünmeden ani bir istekle) aldım.","e2":"He had an impulse to scream.","e2t":"Bağırma dürtüsü hissetti."},{"w":"inaccurate","tr":"yanlış / hatalı","te":"Adjective","tt":"Sıfat","de":"Not correct or exact","dt":"Doğru veya kesin olmayan","e1":"The report was inaccurate.","e1t":"Rapor hatalıydı.","e2":"Her memory of the event was inaccurate.","e2t":"Olayla ilgili hafızası yanlıştı."},{"w":"inadequate","tr":"yetersiz","te":"Adjective","tt":"Sıfat","de":"Not enough or not good enough","dt":"Yeterli olmayan veya yeterince iyi olmayan","e1":"The food supply was inadequate.","e1t":"Yiyecek arzı yetersizdi.","e2":"I feel inadequate for this job.","e2t":"Kendimi bu iş için yetersiz hissediyorum."},{"w":"inappropriate","tr":"uygunsuz / yerinde olmayan","te":"Adjective","tt":"Sıfat","de":"Not suitable or right for a situation","dt":"Bir durum için uygun veya doğru olmayan","e1":"His behavior was inappropriate for a teacher.","e1t":"Davranışı bir öğretmen için uygunsuzdu.","e2":"Is this dress inappropriate?","e2t":"Bu elbise uygunsuz mu?"},{"w":"incentive","tr":"teşvik / özendirici","te":"Noun","tt":"İsim","de":"Something that encourages you to work harder","dt":"Sizi daha sıkı çalışmaya teşvik eden şey","e1":"The company offers a cash incentive for good sales.","e1t":"Şirket iyi satışlar için nakit teşviki sunuyor.","e2":"There is little incentive for them to work.","e2t":"Çalışmaları için pek bir teşvik yok."},{"w":"incident","tr":"olay","te":"Noun","tt":"İsim","de":"An event, often one that is unpleasant or unusual","dt":"Genellikle hoş olmayan veya sıra dışı olan olay","e1":"The police are investigating the incident.","e1t":"Polis olayı araştırıyor.","e2":"It was an isolated incident.","e2t":"Bu münferit (tekil) bir olaydı."},{"w":"inclusion","tr":"dahil etme","te":"Noun","tt":"İsim","de":"The act of including someone or something","dt":"Birini veya bir şeyi dahil etme eylemi","e1":"The inclusion of women in the team is important.","e1t":"Kadınların takıma dahil edilmesi önemlidir.","e2":"The price includes the inclusion of breakfast.","e2t":"Fiyata kahvaltının dahil edilmesi de dahildir."},{"w":"income","tr":"gelir / kazanç","te":"Noun","tt":"İsim","de":"Money that is earned from work or investments","dt":"İşten veya yatırımlardan kazanılan para","e1":"What is your annual income?","e1t":"Yıllık geliriniz nedir?","e2":"People with low incomes need help.","e2t":"Düşük gelirli insanların yardıma ihtiyacı var."},{"w":"incomplete","tr":"eksik / tamamlanmamış","te":"Adjective","tt":"Sıfat","de":"Not finished or not whole","dt":"Bitmemiş veya bütün olmayan","e1":"The report is still incomplete.","e1t":"Rapor hala eksik.","e2":"An incomplete set of tools.","e2t":"Eksik bir alet takımı."},{"w":"incorporate","tr":"dahil etmek / bünyesine katmak","te":"Verb","tt":"Fiil","de":"To include something as part of something larger","dt":"Bir şeyi daha büyük bir şeyin parçası olarak dahil etmek","e1":"We should incorporate your ideas into the plan.","e1t":"Fikirlerini plana dahil etmeliyiz.","e2":"The new car incorporates many safety features.","e2t":"Yeni araba birçok güvenlik özelliğini bünyesinde barındırıyor."},{"w":"increasingly","tr":"giderek daha fazla","te":"Adverb","tt":"Zarf","de":"More and more","dt":"Gittikçe daha çok","e1":"The situation is becoming increasingly difficult.","e1t":"Durum giderek daha zor hale geliyor.","e2":"People are increasingly worried about the environment.","e2t":"İnsanlar çevre konusunda giderek daha fazla endişeleniyor."},{"w":"incredible","tr":"inanılmaz","te":"Adjective","tt":"Sıfat","de":"Impossible or very difficult to believe","dt":"İnanması imkansız veya çok zor","e1":"It was an incredible performance.","e1t":"İnanılmaz bir performanstı.","e2":"The news is absolutely incredible.","e2t":"Haberler kesinlikle inanılmaz."},{"w":"incur","tr":"maruz kalmak / (masraf) açmak","te":"Verb","tt":"Fiil","de":"To experience something unpleasant as a result of actions","dt":"Eylemlerin sonucu olarak hoş olmayan bir şeye maruz kalmak","e1":"He incurred heavy losses.","e1t":"Büyük kayıplara maruz kaldı.","e2":"You will incur a penalty if you pay late.","e2t":"Geç ödeme yaparsanız bir cezaya maruz kalırsınız."},{"w":"independence","tr":"bağımsızlık","te":"Noun","tt":"İsim","de":"Freedom from control by another country or person","dt":"Başka bir ülke veya kişinin kontrolünden özgür olma","e1":"Turkey celebrated its independence day.","e1t":"Türkiye bağımsızlık gününü kutladı.","e2":"She values her independence.","e2t":"Bağımsızlığına değer veriyor."},{"w":"indication","tr":"belirti / gösterge","te":"Noun","tt":"İsim","de":"A sign that something exists or is likely to happen","dt":"Bir şeyin var olduğuna veya olma ihtimali olduğuna dair işaret","e1":"There are few indications of a recovery.","e1t":"İyileşmeye dair az belirti var.","e2":"He gave no indication of his plans.","e2t":"Planlarına dair hiçbir işaret vermedi."},{"w":"indicator","tr":"gösterge / sinyal","te":"Noun","tt":"İsim","de":"Something that shows what a situation is like","dt":"Bir durumun nasıl olduğunu gösteren şey","e1":"Economic indicators are positive.","e1t":"Ekonomik göstergeler olumlu.","e2":"Use your indicators when turning left.","e2t":"Sola dönerken sinyallerinizi (göstergelerinizi) kullanın."},{"w":"indispensable","tr":"vazgeçilmez","te":"Adjective","tt":"Sıfat","de":"Completely necessary","dt":"Tamamen gerekli","e1":"Air is indispensable to life.","e1t":"Hava yaşam için vazgeçilmezdir.","e2":"He is an indispensable member of the team.","e2t":"O takımın vazgeçilmez bir üyesidir."},{"w":"individual","tr":"bireysel / birey","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to one person; a single person","dt":"Bir kişiyle ilgili; tek bir kişi","e1":"We need to respect individual rights.","e1t":"Bireysel haklara saygı duymalıyız.","e2":"Each individual has a different opinion.","e2t":"Her bireyin farklı bir görüşü vardır."},{"w":"induce","tr":"neden olmak / ikna etmek","te":"Verb","tt":"Fiil","de":"To cause something to happen or to persuade","dt":"Bir şeyin olmasına neden olmak veya ikna etmek","e1":"These pills may induce sleep.","e1t":"Bu haplar uykuya neden olabilir (uyku getirebilir).","e2":"Nothing could induce him to change his mind.","e2t":"Hiçbir şey onu fikrini değiştirmeye ikna edemezdi."},{"w":"indulge","tr":"şımartmak / tadını çıkarmak","te":"Verb","tt":"Fiil","de":"To allow yourself or another to have something enjoyable","dt":"Kendinizin veya bir başkasının keyifli bir şeye sahip olmasına izin vermek","e1":"Go on, indulge yourself!","e1t":"Hadi, kendini şımart (keyfine bak)!","e2":"They indulged the child too much.","e2t":"Çocuğu çok fazla şımarttılar."},{"w":"industrial","tr":"endüstriyel / sanayi ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to industry","dt":"Sanayi ile ilgili","e1":"The city has a large industrial zone.","e1t":"Şehrin büyük bir sanayi bölgesi var.","e2":"Industrial production has increased.","e2t":"Sanayi üretimi arttı."},{"w":"industrialize","tr":"sanayileştirmek","te":"Verb","tt":"Fiil","de":"To develop industry in a country or area","dt":"Bir ülke veya bölgede sanayiyi geliştirmek","e1":"The country began to industrialize in the 19th century.","e1t":"Ülke 19. yüzyılda sanayileşmeye başladı.","e2":"An industrialized nation.","e2t":"Sanayileşmiş bir ulus."},{"w":"inefficiency","tr":"verimsizlik","te":"Noun","tt":"İsim","de":"Lack of efficiency","dt":"Verimlilik eksikliği","e1":"The company is suffering from inefficiency.","e1t":"Şirket verimsizlikten muzdarip.","e2":"We need to reduce bureaucracy and inefficiency.","e2t":"Bürokrasiyi ve verimsizliği azaltmalıyız."},{"w":"inevitable","tr":"kaçınılmaz","te":"Adjective","tt":"Sıfat","de":"Certain to happen and unable to be avoided","dt":"Gerçekleşeceği kesin olan ve kaçınılamayan","e1":"Change is inevitable.","e1t":"Değişim kaçınılmazdır.","e2":"It was an inevitable result of his actions.","e2t":"Bu, onun eylemlerinin kaçınılmaz bir sonucuydu."},{"w":"inexpensive","tr":"ucuz / pahalı olmayan","te":"Adjective","tt":"Sıfat","de":"Not costing a lot of money","dt":"Çok paraya mal olmayan","e1":"This is an inexpensive restaurant.","e1t":"Bu ucuz (pahalı olmayan) bir restorandır.","e2":"I am looking for an inexpensive gift.","e2t":"Ucuz bir hediye arıyorum."},{"w":"infant","tr":"bebek (yeni doğan)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very young child or baby","dt":"Çok genç çocuk veya bebek","e1":"The health of the infant is stable.","e1t":"Bebeğin sağlığı stabil.","e2":"She works in an infant school.","e2t":"Bir anaokulunda (bebek okulunda) çalışıyor."},{"w":"infect","tr":"enfekte etmek / bulaştırmak","te":"Verb","tt":"Fiil","de":"To pass a disease or to contaminate","dt":"Bir hastalığı geçirmek veya kirletmek","e1":"The virus can infect anyone.","e1t":"Virüs herkese bulaşabilir.","e2":"Don't let the wound get infected.","e2t":"Yaranın enfekte olmasına (mikrop kapmasına) izin verme."},{"w":"infectious","tr":"bulaşıcı","te":"Adjective","tt":"Sıfat","de":"Able to be passed from one person to another","dt":"Bir kişiden diğerine geçebilen","e1":"Flu is a highly infectious disease.","e1t":"Grip oldukça bulaşıcı bir hastalıktır.","e2":"Her laughter was infectious.","e2t":"Gülüşü bulaşıcıydı (herkesi güldürdü)."},{"w":"infer","tr":"sonuç çıkarmak / anlam çıkarmak","te":"Verb","tt":"Fiil","de":"To form an opinion from the information you have","dt":"Sahip olduğunuz bilgiden bir fikir oluşturmak","e1":"What can we infer from these results?","e1t":"Bu sonuçlardan ne sonuç çıkarabiliriz?","e2":"I inferred from her expression that she was angry.","e2t":"İfadesinden kızgın olduğu sonucunu çıkardım."},{"w":"inflate","tr":"şişirmek","te":"Verb","tt":"Fiil","de":"To fill something with air or gas","dt":"Bir şeyi hava veya gazla doldurmak","e1":"Use a pump to inflate the tires.","e1t":"Lastikleri şişirmek için pompa kullanın.","e2":"They inflated the balloons for the party.","e2t":"Parti için balonları şişirdiler."},{"w":"inflation","tr":"enflasyon","te":"Noun","tt":"İsim","de":"A general increase in prices","dt":"Fiyatlardaki genel artış","e1":"The government is trying to control inflation.","e1t":"Hükümet enflasyonu kontrol etmeye çalışıyor.","e2":"High inflation reduces purchasing power.","e2t":"Yüksek enflasyon alım gücünü azaltır."},{"w":"influential","tr":"etkili / sözü geçen","te":"Adjective","tt":"Sıfat","de":"Having a lot of influence or power","dt":"Çok fazla etkiye veya güce sahip olma","e1":"He is an influential politician.","e1t":"O, nüfuzlu (etkili) bir politikacıdır.","e2":"Her book was highly influential.","e2t":"Kitabı oldukça etkiliydi."},{"w":"inform","tr":"bilgilendirmek / haber vermek","te":"Verb","tt":"Fiil","de":"To give someone information","dt":"Birine bilgi vermek","e1":"Please inform us of any changes.","e1t":"Lütfen herhangi bir değişiklikten bizi bilgilendirin.","e2":"I informed him of my decision.","e2t":"Kararımı ona bildirdim."},{"w":"inhabit","tr":"yaşamak / ikamet etmek","te":"Verb","tt":"Fiil","de":"To live in a particular place","dt":"Belirli bir yerde yaşamak","e1":"Many rare animals inhabit these woods.","e1t":"Bu ormanlarda birçok nadir hayvan yaşar.","e2":"The island is not inhabited.","e2t":"Adada kimse yaşamıyor (meskun değil)."},{"w":"inhabitant","tr":"sakin / yaşayan","te":"Noun","tt":"İsim","de":"A person or animal that lives in a place","dt":"Bir yerde yaşayan kişi veya hayvan","e1":"The city has over two million inhabitants.","e1t":"Şehrin iki milyondan fazla sakini var.","e2":"The local inhabitants are very friendly.","e2t":"Yerel halk (sakinler) çok arkadaş canlısı."},{"w":"inherent","tr":"doğuştan gelen / özünde olan","te":"Adjective","tt":"Sıfat","de":"Existing as a natural or basic part of something","dt":"Bir şeyin doğal veya temel bir parçası olarak var olan","e1":"There are inherent risks in this job.","e1t":"Bu işte doğuştan gelen (yapısında olan) riskler vardır.","e2":"Freedom is an inherent right.","e2t":"Özgürlük doğuştan gelen bir haktır."},{"w":"inherit","tr":"miras almak","te":"Verb","tt":"Fiil","de":"To receive money or property from someone who has died","dt":"Ölen birinden para veya mülk almak","e1":"She inherited a fortune from her grandmother.","e1t":"Büyükannesinden bir servet miras aldı.","e2":"He inherited his father's blue eyes.","e2t":"Babasının mavi gözlerini miras aldı (genetik olarak)."},{"w":"initially","tr":"başlangıçta / ilk etapta","te":"Adverb","tt":"Zarf","de":"At the beginning","dt":"Başlangıçta","e1":"Initially, I thought he was joking.","e1t":"Başlangıçta şaka yaptığını sanmıştım.","e2":"The project was initially very successful.","e2t":"Proje başlangıçta çok başarılıydı."},{"w":"initiative","tr":"girişim / hamle","te":"Noun","tt":"İsim","de":"A new plan or action; the ability to start things","dt":"Yeni bir plan veya eylem; bir şeyleri başlatma yeteneği","e1":"The government has started a new peace initiative.","e1t":"Hükümet yeni bir barış girişimi başlattı.","e2":"You need to show more initiative.","e2t":"Daha fazla girişkenlik göstermelisin."},{"w":"inject","tr":"enjekte etmek / iğne yapmak","te":"Verb","tt":"Fiil","de":"To use a needle to put medicine into the body","dt":"Vücuda ilaç koymak için iğne kullanmak","e1":"The nurse injected the vaccine.","e1t":"Hemşire aşıyı enjekte etti.","e2":"He has to inject insulin every day.","e2t":"Her gün insülin iğnesi yapması gerekiyor."},{"w":"innovate","tr":"yenilik yapmak","te":"Verb","tt":"Fiil","de":"To introduce new ideas or methods","dt":"Yeni fikirler veya yöntemler sunmak","e1":"Companies must innovate to survive.","e1t":"Şirketler hayatta kalmak için yenilik yapmalıdır.","e2":"We are constantly trying to innovate.","e2t":"Sürekli yenilik yapmaya çalışıyoruz."},{"w":"innovation","tr":"yenilik / inovasyon","te":"Noun","tt":"İsim","de":"A new idea, design, or method","dt":"Yeni fikir, tasarım veya yöntem","e1":"Technical innovation is key to growth.","e1t":"Teknik yenilik büyümenin anahtarıdır.","e2":"The new product is a great innovation.","e2t":"Yeni ürün büyük bir yeniliktir."},{"w":"innovative","tr":"yenilikçi","te":"Adjective","tt":"Sıfat","de":"Using new ideas and methods","dt":"Yeni fikirler ve yöntemler kullanan","e1":"He has a very innovative approach to design.","e1t":"Tasarıma karşı çok yenilikçi bir yaklaşımı var.","e2":"They use innovative technology.","e2t":"Yenilikçi teknoloji kullanıyorlar."},{"w":"input","tr":"girdi / veri girişi","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something such as energy or money that is put into a system","dt":"Bir sisteme konulan enerji veya para gibi bir şey","e1":"We need more input from the staff.","e1t":"Personelden daha fazla katkı (girdi) bekliyoruz.","e2":"Please enter the input data.","e2t":"Lütfen girdi verilerini girin."},{"w":"inquiry / enquiry","tr":"sorgu / soruşturma / bilgi isteme","te":"Noun","tt":"İsim","de":"A formal process to find out the facts","dt":"Gerçekleri öğrenmek için resmi bir süreç","e1":"The police are conducting a murder inquiry.","e1t":"Polis bir cinayet soruşturması yürütüyor.","e2":"I am writing in inquiry about your products.","e2t":"Ürünleriniz hakkında bilgi almak için yazıyorum."},{"w":"insane","tr":"çılgın / deli","te":"Adjective","tt":"Sıfat","de":"Mad or very silly","dt":"Deli veya çok aptalca","e1":"It was an insane thing to do.","e1t":"Yapılacak çılgınca bir şeydi.","e2":"You must be insane!","e2t":"Deli olmalısın!"},{"w":"insert","tr":"araya eklemek / takmak / yerleştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put something into something else","dt":"Bir şeyi başka bir şeyin içine koymak","e1":"Insert the key into the lock.","e1t":"Anahtarı kilide takın.","e2":"He inserted a few words into the sentence.","e2t":"Cümleye birkaç kelime ekledi."},{"w":"insider","tr":"içeriden biri","te":"Noun","tt":"İsim","de":"A person who has special knowledge about an organization","dt":"Bir organizasyon hakkında özel bilgisi olan kişi","e1":"He is a government insider.","e1t":"O, hükümetin içinden biridir.","e2":"Insider trading is illegal.","e2t":"İçeriden bilgi alarak ticaret yapmak yasa dışıdır."},{"w":"insight","tr":"içgörü / anlayış","te":"Noun","tt":"İsim","de":"A clear and deep understanding of a complex problem","dt":"Karmaşık bir sorunu net ve derinlemesine anlama","e1":"The book gives a great insight into Turkish history.","e1t":"Kitap Türk tarihine harika bir içgörü sağlıyor.","e2":"I hope this helps you gain more insight.","e2t":"Umarım bu, daha fazla anlayış kazanmanıza yardımcı olur."},{"w":"inspect","tr":"denetlemek / incelemek","te":"Verb","tt":"Fiil","de":"To look at something carefully to check it","dt":"Kontrol etmek için bir şeye dikkatlice bakmak","e1":"The health inspector will visit today.","e1t":"Sağlık müfettişi bugün ziyaret edecek.","e2":"They inspect the bridge every year.","e2t":"Köprüyü her yıl denetlerler."},{"w":"inspection","tr":"denetim / teftiş","te":"Noun","tt":"İsim","de":"The act of inspecting something","dt":"Bir şeyi denetleme eylemi","e1":"The car passed the technical inspection.","e1t":"Araba teknik denetimi geçti.","e2":"A routine safety inspection.","e2t":"Rutin bir güvenlik denetimi."},{"w":"inspector","tr":"müfettiş / denetleyici","te":"Noun","tt":"İsim","de":"A person whose job is to inspect things","dt":"İşi şeyleri denetlemek olan kişi","e1":"He works as a school inspector.","e1t":"Okul müfettişi olarak çalışıyor.","e2":"The fire inspector checked the building.","e2t":"İtfaiye denetleyicisi binayı kontrol etti."},{"w":"inspiration","tr":"ilham","te":"Noun","tt":"İsim","de":"A sudden good idea or someone who gives you ideas","dt":"Aniden gelen iyi fikir veya size fikir veren birisi","e1":"The sunset was the inspiration for his painting.","e1t":"Gün batımı onun tablosunun ilham kaynağıydı.","e2":"She is an inspiration to us all.","e2t":"O hepimiz için bir ilham kaynağıdır."},{"w":"inspire","tr":"ilham vermek","te":"Verb","tt":"Fiil","de":"To make someone want to do something or feel a certain way","dt":"Birinin bir şeyi yapmasını veya belirli bir şekilde hissetmesini sağlamak","e1":"His speech inspired the students.","e1t":"Konuşması öğrencilere ilham verdi.","e2":"We want to inspire new ideas.","e2t":"Yeni fikirlere ilham vermek istiyoruz."},{"w":"install","tr":"kurmak / monte etmek","te":"Verb","tt":"Fiil","de":"To put a piece of equipment or software in place","dt":"Bir ekipmanı veya yazılımı yerine koymak (hazır hale getirmek)","e1":"I need to install a new printer.","e1t":"Yeni bir yazıcı kurmam gerekiyor.","e2":"The technician installed the air conditioner.","e2t":"Teknisyen klimayı monte etti."},{"w":"instance","tr":"örnek / durum","te":"Noun","tt":"İsim","de":"A particular example of something","dt":"Bir şeyin belirli bir örneği","e1":"For instance, you could try calling him.","e1t":"Örneğin (örnek olarak), onu aramayı deneyebilirsin.","e2":"There are several instances of this problem.","e2t":"Bu sorunun birkaç örneği (durumu) var."},{"w":"instant","tr":"anlık / hemen olan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Happening immediately","dt":"Hemen gerçekleşen","e1":"The book was an instant success.","e1t":"Kitap anında bir başarı oldu.","e2":"I want an answer this instant!","e2t":"Hemen şu an bir cevap istiyorum!"},{"w":"instantly","tr":"hemen / anında","te":"Adverb","tt":"Zarf","de":"Immediately","dt":"Derhal","e1":"The driver died instantly in the crash.","e1t":"Sürücü kazada anında hayatını kaybetti.","e2":"She recognized him instantly.","e2t":"Onu anında tanıdı."},{"w":"instinct","tr":"içgüdü","te":"Noun","tt":"İsim","de":"A natural behavior or reaction","dt":"Doğal davranış veya tepki","e1":"Birds follow their instinct to fly south.","e1t":"Kuşlar güneye uçmak için içgüdülerini takip ederler.","e2":"My first instinct was to run.","e2t":"İlk içgüdüm kaçmaktı."},{"w":"institutional","tr":"kurumsal","te":"Adjective","tt":"Sıfat","de":"Relating to a large organization","dt":"Büyük bir organizasyonla ilgili","e1":"We need institutional support for the project.","e1t":"Proje için kurumsal desteğe ihtiyacımız var.","e2":"Institutional investors.","e2t":"Kurumsal yatırımcılar."},{"w":"instruct","tr":"talimat vermek / öğretmek","te":"Verb","tt":"Fiil","de":"To tell someone what to do or to teach","dt":"Birine ne yapacağını söylemek veya öğretmek","e1":"He instructed me to wait here.","e1t":"Bana burada beklememi talimat verdi.","e2":"She instructs students in music.","e2t":"Öğrencilere müzik öğretiyor (ders veriyor)."},{"w":"instrumental","tr":"etkili / aracı / enstrümantal","te":"Adjective","tt":"Sıfat","de":"Being important in making something happen","dt":"Bir şeyin gerçekleşmesinde önemli olma","e1":"He was instrumental in solving the problem.","e1t":"Sorunun çözümünde etkili oldu (aracı oldu).","e2":"This is an instrumental piece of music.","e2t":"Bu enstrümantal bir müzik parçasıdır."},{"w":"insufficient","tr":"yetersiz","te":"Adjective","tt":"Sıfat","de":"Not enough","dt":"Kafi olmayan","e1":"The evidence was insufficient to prove his guilt.","e1t":"Kanıt onun suçluluğunu kanıtlamak için yetersizdi.","e2":"We have insufficient funds.","e2t":"Yetersiz fonumuz (paramız) var."},{"w":"insure","tr":"sigortalamak","te":"Verb","tt":"Fiil","de":"To pay money to a company so they pay you if something is lost/damaged","dt":"Kaybolma/hasar durumunda ödeme yapmaları için bir şirkete para ödemek","e1":"You should insure your house against fire.","e1t":"Evini yangına karşı sigortalamalısın.","e2":"The car is insured for 50,000 dollars.","e2t":"Araba 50.000 dolara sigortalıdır."},{"w":"intact","tr":"sağlam / el değmemiş / bozulmamış","te":"Adjective","tt":"Sıfat","de":"Complete and not damaged","dt":"Tam ve hasar görmemiş","e1":"The historic building is still intact.","e1t":"Tarihi bina hala sağlam (ayakta).","e2":"The package arrived intact.","e2t":"Paket sapasağlam ulaştı."},{"w":"integral","tr":"ayrılmaz / tamamlayıcı","te":"Adjective","tt":"Sıfat","de":"Necessary and important as a part of a whole","dt":"Bir bütünün parçası olarak gerekli ve önemli","e1":"Music is an integral part of his life.","e1t":"Müzik onun hayatının ayrılmaz bir parçasıdır.","e2":"He is an integral member of the team.","e2t":"O takımın tamamlayıcı (temel) bir üyesidir."},{"w":"integrate","tr":"bütünleştirmek / entegre etmek","te":"Verb","tt":"Fiil","de":"To combine two or more things to make them work together","dt":"Birlikte çalışmalarını sağlamak için iki veya daha fazla şeyi birleştirmek","e1":"We need to integrate the new system.","e1t":"Yeni sistemi entegre etmeliyiz.","e2":"It's difficult to integrate into a new society.","e2t":"Yeni bir topluma uyum sağlamak (bütünleşmek) zordur."},{"w":"integration","tr":"entegrasyon / bütünleşme","te":"Noun","tt":"İsim","de":"The process of combining things","dt":"Şeyleri birleştirme süreci","e1":"The integration of the two companies took a year.","e1t":"İki şirketin birleşmesi (entegrasyonu) bir yıl sürdü.","e2":"We believe in racial integration.","e2t":"Irksal bütünleşmeye inanıyoruz."},{"w":"integrity","tr":"dürüstlük / bütünlük","te":"Noun","tt":"İsim","de":"Honesty or the state of being complete","dt":"Dürüstlük veya tam olma durumu","e1":"He is a man of great integrity.","e1t":"O büyük dürüstlük sahibi bir adamdır.","e2":"We must maintain the integrity of the database.","e2t":"Veri tabanının bütünlüğünü korumalıyız."},{"w":"intend","tr":"niyet etmek / amaçlamak","te":"Verb","tt":"Fiil","de":"To have as a plan or purpose","dt":"Plan veya amaç olarak sahip olmak","e1":"I intend to visit my parents next week.","e1t":"Gelecek hafta ailemi ziyaret etmeye niyetim var.","e2":"What do you intend to do?","e2t":"Ne yapmayı amaçlıyorsun?"},{"w":"intense","tr":"yoğun / şiddetli","te":"Adjective","tt":"Sıfat","de":"Very strong or extreme","dt":"Çok güçlü veya aşırı","e1":"The heat was intense.","e1t":"Isı çok şiddetliydi.","e2":"He has an intense interest in history.","e2t":"Tarihe karşı yoğun bir ilgisi var."},{"w":"intensity","tr":"yoğunluk / şiddet","te":"Noun","tt":"İsim","de":"The quality of being intense","dt":"Yoğun veya şiddetli olma özelliği","e1":"The intensity of the light was blinding.","e1t":"Işığın şiddeti göz kamaştırıcıydı.","e2":"We are working with high intensity.","e2t":"Yüksek yoğunlukla çalışıyoruz."},{"w":"interact","tr":"etkileşimde bulunmak","te":"Verb","tt":"Fiil","de":"To communicate or work with someone","dt":"Biriyle iletişim kurmak veya çalışmak","e1":"The computer allows you to interact with other users.","e1t":"Bilgisayar diğer kullanıcılarla etkileşim kurmanıza olanak tanır.","e2":"Children need to interact with each other.","e2t":"Çocukların birbirleriyle etkileşim kurması gerekir."},{"w":"interaction","tr":"etkileşim","te":"Noun","tt":"İsim","de":"The act of interacting","dt":"Etkileşim eylemi","e1":"Social interaction is important for health.","e1t":"Sosyal etkileşim sağlık için önemlidir.","e2":"The interaction between the two chemicals.","e2t":"İki kimyasal arasındaki etkileşim."},{"w":"interfere","tr":"müdahale etmek / karışmak","te":"Verb","tt":"Fiil","de":"To involve yourself in something that is not your business","dt":"Sizi ilgilendirmeyen bir şeye dahil olmak","e1":"Don't interfere in my private life.","e1t":"Özel hayatıma karışma.","e2":"The noise interferes with my sleep.","e2t":"Gürültü uykuma müdahale ediyor (engelliyor)."},{"w":"internal","tr":"iç / dahili","te":"Adjective","tt":"Sıfat","de":"Inside an object, body, or organization","dt":"Bir nesnenin, vücudun veya organizasyonun içinde","e1":"He has internal injuries.","e1t":"İç organ yaralanmaları (iç kanaması) var.","e2":"The company is doing an internal audit.","e2t":"Şirket dahili bir denetim yapıyor."},{"w":"interpret","tr":"yorumlamak / tercüme etmek (sözlü)","te":"Verb","tt":"Fiil","de":"To explain the meaning of something or to translate","dt":"Bir şeyin anlamını açıklamak veya tercüme etmek","e1":"How do you interpret this poem?","e1t":"Bu şiiri nasıl yorumlarsın?","e2":"She interpreted the speech for the visitors.","e2t":"Konuşmayı ziyaretçiler için tercüme etti (çevirdi)."},{"w":"interpretation","tr":"yorum / çeviri","te":"Noun","tt":"İsim","de":"An explanation or opinion of what something means","dt":"Bir şeyin ne anlama geldiğine dair açıklama veya görüş","e1":"What is your interpretation of the data?","e1t":"Verilere dair yorumunuz nedir?","e2":"There are many interpretations of this law.","e2t":"Bu yasanın birçok yorumu var."},{"w":"interrupt","tr":"sözünü kesmek / bölmek","te":"Verb","tt":"Fiil","de":"To stop someone while they are talking or doing something","dt":"Biri konuşurken veya bir şey yaparken onu durdurmak","e1":"Sorry to interrupt, but there is a phone call for you.","e1t":"Böldüğüm için üzgünüm ama sizin için bir telefon var.","e2":"Don't interrupt me while I'm working.","e2t":"Çalışırken sözümü kesme (beni bölme)."},{"w":"interval","tr":"ara / aralık","te":"Noun","tt":"İsim","de":"A period of time between two events","dt":"İki olay arasındaki zaman dilimi","e1":"There will be a short interval for coffee.","e1t":"Kahve için kısa bir ara verilecek.","e2":"We have inspections at regular intervals.","e2t":"Düzenli aralıklarla denetimlerimiz var."},{"w":"intervene","tr":"müdahale etmek / araya girmek","te":"Verb","tt":"Fiil","de":"To intentionally become involved in a difficult situation","dt":"Zor bir duruma kasıtlı olarak dahil olmak","e1":"The police had to intervene to stop the fight.","e1t":"Kavgayı durdurmak için polisin müdahale etmesi gerekti.","e2":"I'll intervene if the situation gets worse.","e2t":"Durum kötüleşirse araya gireceğim."},{"w":"intervention","tr":"müdahale","te":"Noun","tt":"İsim","de":"The act of intervening","dt":"Müdahale etme eylemi","e1":"Military intervention was necessary.","e1t":"Askeri müdahale gerekliydi.","e2":"Early intervention is key to success.","e2t":"Erken müdahale başarının anahtarıdır."},{"w":"intimate","tr":"samimi / yakın / mahrem","te":"Adjective","tt":"Sıfat","de":"Having a very close friendship or personal relationship","dt":"Çok yakın bir arkadaşlığa veya kişisel ilişkiye sahip olma","e1":"They are intimate friends.","e1t":"Onlar samimi (yakın) arkadaştırlar.","e2":"We had an intimate conversation.","e2t":"Baş başa (mahrem/yakın) bir görüşme yaptık."},{"w":"intimidate","tr":"gözdağı vermek / korkutmak","te":"Verb","tt":"Fiil","de":"To frighten someone, especially to make them do something","dt":"Birini, özellikle bir şeyi yapmasını sağlamak için korkutmak","e1":"Don't let him intimidate you.","e1t":"Onun gözünü korkutmasına izin verme.","e2":"The size of the project intimidated the team.","e2t":"Projenin büyüklüğü takımın gözünü korkuttu."},{"w":"invade","tr":"istila etmek / girmek","te":"Verb","tt":"Fiil","de":"To enter a country or place with an army","dt":"Bir orduyla bir ülkeye veya yere girmek","e1":"Germany invaded Poland in 1939.","e1t":"Almanya 1939'da Polonya'yı istila etti.","e2":"Tourists invade the city every summer.","e2t":"Her yaz turistler şehri istila eder (doldurur)."},{"w":"invasion","tr":"istila / saldırı","te":"Noun","tt":"İsim","de":"The act of invading","dt":"İstila etme eylemi","e1":"The invasion of Iraq.","e1t":"Irak'ın istilası.","e2":"It was an invasion of my privacy.","e2t":"Bu, özel hayatımın bir ihlaliydi (istilasıydı)."},{"w":"investigate","tr":"araştırmak / incelemek","te":"Verb","tt":"Fiil","de":"To examine a crime, problem, or statement to find the truth","dt":"Gerçeği bulmak için bir suçu, sorunu veya ifadeyi incelemek","e1":"The police are investigating the murder.","e1t":"Polis cinayeti araştırıyor.","e2":"We need to investigate all the options.","e2t":"Tüm seçenekleri incelememiz gerekiyor."},{"w":"investigation","tr":"araştırma / soruşturma","te":"Noun","tt":"İsim","de":"The act of investigating something","dt":"Bir şeyi araştırma eylemi","e1":"A criminal investigation is underway.","e1t":"Bir ceza soruşturması yürütülüyor.","e2":"The result of the investigation will be published soon.","e2t":"Soruşturmanın sonucu yakında yayınlanacak."},{"w":"investigator","tr":"araştırmacı / dedektif","te":"Noun","tt":"İsim","de":"A person whose job is to investigate","dt":"İşi araştırma yapmak olan kişi","e1":"He is a private investigator.","e1t":"O bir özel dedektiftir (araştırmacıdır).","e2":"The fire investigators are at the scene.","e2t":"Yangın araştırmacıları olay yerinde."},{"w":"invisible","tr":"görünmez","te":"Adjective","tt":"Sıfat","de":"Impossible to see","dt":"Görülmesi imkansız","e1":"Bacteria are invisible to the naked eye.","e1t":"Bakteriler çıplak gözle görünmezler.","e2":"He felt invisible at the party.","e2t":"Partide kendini görünmez (fark edilmeyen) biri gibi hissetti."},{"w":"involvement","tr":"dahil olma / katılım","te":"Noun","tt":"İsim","de":"The act of taking part in something","dt":"Bir şeye katılma eylemi","e1":"Her involvement in the project was crucial.","e1t":"Onun projeye katılımı (dahil olması) çok önemliydi.","e2":"He denied any involvement in the crime.","e2t":"Suça herhangi bir katılımını reddetti."},{"w":"ironic","tr":"ironik / alaycı","te":"Adjective","tt":"Sıfat","de":"Strange or funny because of being the opposite of what is expected","dt":"Beklenenin tersi olduğu için garip veya komik olan","e1":"It is ironic that the fire station burned down.","e1t":"İtfaiye istasyonunun yanması ironiktir.","e2":"He made an ironic comment.","e2t":"İronik (alaycı) bir yorum yaptı."},{"w":"irony","tr":"ironi","te":"Noun","tt":"İsim","de":"A situation that is strange because it is the opposite of what you expected","dt":"Beklediğinizin tersi olduğu için garip olan durum","e1":"The irony of the situation is that...","e1t":"Durumun ironisi şudur ki...","e2":"There was a touch of irony in her voice.","e2t":"Sesinde bir ironi tınısı vardı."},{"w":"irregular","tr":"düzensiz","te":"Adjective","tt":"Sıfat","de":"Not happening at equal intervals; not straight","dt":"Eşit aralıklarla gerçekleşmeyen; düz olmayan","e1":"He has an irregular heartbeat.","e1t":"Düzensiz bir kalp atışı var.","e2":"These are irregular verbs.","e2t":"Bunlar düzensiz fiillerdir."},{"w":"irrelevant","tr":"alakasız / ilgisiz","te":"Adjective","tt":"Sıfat","de":"Not related to what is being discussed","dt":"Tartışılan konuyla ilgili olmayan","e1":"That information is irrelevant to the case.","e1t":"Bu bilgi dava ile alakasız.","e2":"His comments were completely irrelevant.","e2t":"Yorumları tamamen ilgisizdi."},{"w":"irrigate","tr":"sulamak","te":"Verb","tt":"Fiil","de":"To supply land with water so that crops grow","dt":"Mahsullerin büyümesi için araziye su sağlamak","e1":"Farmers irrigate their fields in summer.","e1t":"Çiftçiler yazın tarlalarını sularlar.","e2":"The Nile is used to irrigate the desert.","e2t":"Nil Nehri çölü sulamak için kullanılır."},{"w":"irritate","tr":"kızdırmak / tahriş etmek","te":"Verb","tt":"Fiil","de":"To make someone annoyed; to make a body part painful","dt":"Birini kızdırmak; bir vücut parçasını acıtmak (kaşındırmak)","e1":"His constant complaining irritates me.","e1t":"Sürekli şikayet etmesi beni kızdırıyor.","e2":"The smoke irritated my eyes.","e2t":"Duman gözlerimi tahriş etti."},{"w":"isolation","tr":"izolasyon / yalıtım / yalnızlık","te":"Noun","tt":"İsim","de":"The state of being separate from others","dt":"Diğerlerinden ayrı olma durumu","e1":"The prisoner was kept in isolation.","e1t":"Mahkum tecritte (izolasyonda) tutuldu.","e2":"The isolation of the village is a problem.","e2t":"Köyün yalnızlığı (yalıtılmışlığı) bir sorundur."},{"w":"ivory","tr":"fildişi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard white substance from elephants' tusks","dt":"Fil dişlerinden elde edilen sert beyaz madde","e1":"The trade in ivory is illegal.","e1t":"Fildişi ticareti yasa dışıdır.","e2":"Ivory keys on an old piano.","e2t":"Eski bir piyanodaki fildişi tuşlar."},{"w":"jail","tr":"hapsetmek / hapis","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put someone in prison or the prison itself","dt":"Birini hapse atmak veya hapishanenin kendisi","e1":"He was jailed for three years.","e1t":"Üç yıl hapsedildi.","e2":"He is currently in jail.","e2t":"Şu anda hapiste."},{"w":"jam","tr":"sıkışıklık / reçel / sıkıştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A situation where things cannot move or a fruit spread","dt":"Hareket edilemeyen durum veya meyve ezmesi","e1":"We were stuck in a traffic jam.","e1t":"Trafik sıkışıklığında kaldık.","e2":"I like strawberry jam.","e2t":"Çilek reçelini severim."},{"w":"janitor","tr":"kapıcı / hademe","te":"Noun","tt":"İsim","de":"A person whose job is to clean a large building","dt":"İşi büyük bir binayı temizlemek olan kişi","e1":"The school janitor is very helpful.","e1t":"Okul hademesi çok yardımcıdır.","e2":"He works as a janitor in a hospital.","e2t":"Bir hastanede hademe olarak çalışıyor."},{"w":"jar","tr":"kavanoz","te":"Noun","tt":"İsim","de":"A glass container with a wide top","dt":"Geniş ağızlı cam kap","e1":"A jar of honey.","e1t":"Bir kavanoz bal.","e2":"She put the cookies in a glass jar.","e2t":"Kurabiyeleri cam bir kavanoza koydu."},{"w":"jaw","tr":"çene","te":"Noun","tt":"İsim","de":"The lower part of the face that moves when you talk","dt":"Konuşurken hareket eden yüzün alt kısmı","e1":"He has a broken jaw.","e1t":"Çenesi kırık.","e2":"Sharks have very strong jaws.","e2t":"Köpekbalıklarının çok güçlü çeneleri vardır."},{"w":"jealousy","tr":"kıskançlık","te":"Noun","tt":"İsim","de":"The feeling of being jealous","dt":"Kıskançlık hissi","e1":"Jealousy can ruin a relationship.","e1t":"Kıskançlık bir ilişkiyi mahvedebilir.","e2":"He was filled with jealousy.","e2t":"Kıskançlıkla doluydu."},{"w":"jelly","tr":"jöle / pelte","te":"Noun","tt":"İsim","de":"A soft, sweet, transparent food","dt":"Yumuşak, tatlı, şeffaf yiyecek","e1":"Children love fruit jelly.","e1t":"Çocuklar meyveli jöleyi severler.","e2":"A jar of grape jelly.","e2t":"Bir kavanoz üzüm jölesi."},{"w":"jeopardize","tr":"tehlikeye atmak","te":"Verb","tt":"Fiil","de":"To put something such as a plan or system in danger","dt":"Plan veya sistem gibi bir şeyi tehlikeye atmak","e1":"Bad weather could jeopardize the whole project.","e1t":"Kötü hava tüm projeyi tehlikeye atabilir.","e2":"Don't jeopardize your health.","e2t":"Sağlığını tehlikeye atma."},{"w":"jerk","tr":"sarsmak / aniden çekmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move or pull something suddenly","dt":"Bir şeyi aniden hareket ettirmek veya çekmek","e1":"He jerked the door open.","e1t":"Kapıyı aniden açtı (sarsarak).","e2":"The car started with a jerk.","e2t":"Araba bir sarsıntıyla kalktı."},{"w":"jewel","tr":"mücevher / değerli taş","te":"Noun","tt":"İsim","de":"A valuable stone such as a diamond","dt":"Elmas gibi değerli taş","e1":"She wore a necklace with blue jewels.","e1t":"Mavi mücevherli bir kolye taktı.","e2":"These jewels are worth a fortune.","e2t":"Bu mücevherler bir servet değerinde."},{"w":"jewelry / jewellery","tr":"mücevherat / takı","te":"Noun","tt":"İsim","de":"Decorative objects such as rings and necklaces","dt":"Yüzük ve kolye gibi dekoratif nesneler","e1":"She sells handmade jewelry.","e1t":"El yapımı takılar satıyor.","e2":"I don't wear much jewelry.","e2t":"Çok fazla takı takmam."},{"w":"joint","tr":"eklem / ortak / bağlantı yeri","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A place where two things are joined or shared","dt":"İki şeyin birleştiği veya paylaşıldığı yer","e1":"He has a pain in his knee joint.","e1t":"Diz ekleminde bir ağrı var.","e2":"This was a joint decision.","e2t":"Bu ortak bir karardı."},{"w":"joyful","tr":"neşeli / sevinçli","te":"Adjective","tt":"Sıfat","de":"Very happy","dt":"Çok mutlu","e1":"It was a joyful occasion.","e1t":"Sevinçli bir vesileydi.","e2":"She gave a joyful laugh.","e2t":"Neşeli bir kahkaha attı."},{"w":"judgment / judgement","tr":"yargı / karar / hüküm","te":"Noun","tt":"İsim","de":"An official decision or the ability to make good decisions","dt":"Resmi bir karar veya iyi kararlar verme yeteneği","e1":"We are waiting for the court's judgment.","e1t":"Mahkemenin kararını bekliyoruz.","e2":"Use your best judgment.","e2t":"En iyi muhakemeni (kararını) kullan."},{"w":"juicy","tr":"sulu","te":"Adjective","tt":"Sıfat","de":"Full of juice","dt":"Meyve suyu dolu","e1":"This orange is very juicy.","e1t":"Bu portakal çok sulu.","e2":"A juicy steak.","e2t":"Sulu bir biftek."},{"w":"junction","tr":"kavşak / bağlantı noktası","te":"Noun","tt":"İsim","de":"A place where roads or railways meet","dt":"Yolların veya demiryollarının birleştiği yer","e1":"Turn left at the next junction.","e1t":"Bir sonraki kavşaktan sola dönün.","e2":"The junction is very busy during rush hour.","e2t":"Kavşak iş saatlerinde çok yoğundur."},{"w":"jury","tr":"jüri","te":"Noun","tt":"İsim","de":"A group of people who decide if someone is guilty in court","dt":"Mahkemede birinin suçlu olup olmadığına karar veren grup","e1":"The jury found him not guilty.","e1t":"Jüri onu suçsuz buldu.","e2":"Members of the jury.","e2t":"Jüri üyeleri."},{"w":"justice","tr":"adalet","te":"Noun","tt":"İsim","de":"Fairness in the way people are treated","dt":"İnsanlara davranılma şeklindeki adalet (hakkaniyet)","e1":"We are fighting for social justice.","e1t":"Sosyal adalet için savaşıyoruz.","e2":"The Minister of Justice.","e2t":"Adalet Bakanı."},{"w":"justify","tr":"haklı çıkarmak / gerekçelendirmek","te":"Verb","tt":"Fiil","de":"To give a good reason for something","dt":"Bir şey için iyi bir neden sunmak","e1":"How can you justify such a high price?","e1t":"Bu kadar yüksek bir fiyatı nasıl haklı çıkarabilirsin?","e2":"Nothing can justify violence.","e2t":"Hiçbir şey şiddeti haklı gösteremez."},{"w":"keep up","tr":"devam ettirmek / sürdürmek","te":"Verb","tt":"Fiil","de":"To continue to do something","dt":"Bir şeyi yapmaya devam etmek","e1":"Keep up the good work!","e1t":"İyi çalışmaya devam et!","e2":"He struggled to keep up his grades.","e2t":"Notlarını yüksek tutmak (sürdürmek) için çabaladı."},{"w":"kettle","tr":"çaydanlık / su ısıtıcısı","te":"Noun","tt":"İsim","de":"A container used for boiling water","dt":"Su kaynatmak için kullanılan kap","e1":"I'll put the kettle on.","e1t":"Çaydanlığı (ısıtıcıyı) ateşe koyayım (çalıştırayım).","e2":"The kettle is whistling.","e2t":"Çaydanlık ötüyor."},{"w":"kidnap","tr":"kaçırmak (insan)","te":"Verb","tt":"Fiil","de":"To take someone away by force and keep them prisoner","dt":"Birini zorla alıp götürmek ve tutsak tutmak","e1":"Two businessmen were kidnapped yesterday.","e1t":"Dün iki iş adamı kaçırıldı.","e2":"The child was kidnapped for ransom.","e2t":"Çocuk fidye için kaçırıldı."},{"w":"kidney","tr":"böbrek","te":"Noun","tt":"İsim","de":"One of the two organs that clean the blood","dt":"Kanı temizleyen iki organdan biri","e1":"He needs a kidney transplant.","e1t":"Böbrek nakline ihtiyacı var.","e2":"Kidney stones can be very painful.","e2t":"Böbrek taşları çok ağrılı olabilir."},{"w":"kindness","tr":"nezaket / iyilik","te":"Noun","tt":"İsim","de":"The quality of being kind","dt":"Nazik olma özelliği","e1":"Thank you for your kindness.","e1t":"İyiliğiniz için teşekkürler.","e2":"Kindness costs nothing.","e2t":"Nezaket (iyilik) bedavadır."},{"w":"kingdom","tr":"krallık","te":"Noun","tt":"İsim","de":"A country ruled by a king or queen","dt":"Kral veya kraliçe tarafından yönetilen ülke","e1":"The United Kingdom.","e1t":"Birleşik Krallık.","e2":"He ruled over a vast kingdom.","e2t":"Devasa bir krallığı yönetti."},{"w":"kit","tr":"takım / set / ekipman","te":"Noun","tt":"İsim","de":"A set of tools or equipment for a specific purpose","dt":"Belirli bir amaç için araç veya ekipman seti","e1":"A first","e1t":"aid kit.","e2":"İlk yardım çantası (seti).","e2t":"I bought a model airplane kit."},{"w":"kneel","tr":"diz çökmek","te":"Verb","tt":"Fiil","de":"To go down on your knees","dt":"Dizlerinin üzerine çökmek","e1":"He knelt down to tie his shoes.","e1t":"Ayakkabılarını bağlamak için diz çöktü.","e2":"They knelt in prayer.","e2t":"Dua etmek için diz çöktüler."},{"w":"knit","tr":"örmek","te":"Verb","tt":"Fiil","de":"To make clothes using wool and needles","dt":"Yün ve şiş kullanarak kıyafet yapmak","e1":"My grandmother is knitting a sweater for me.","e1t":"Büyükannem benim için kazak örüyor.","e2":"She learned to knit when she was a child.","e2t":"Örmeyi çocukken öğrendi."},{"w":"knot","tr":"düğüm / bağlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where pieces of string are tied together","dt":"İp parçalarının birbirine bağlandığı yer","e1":"Tie a knot in the end of the string.","e1t":"İpin ucuna bir düğüm at.","e2":"I can't undo this knot.","e2t":"Bu düğümü çözemiyorum."},{"w":"label","tr":"etiket / etiketlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of paper on something that gives information","dt":"Bir şeyin üzerindeki bilgi veren kağıt parçası","e1":"Read the label before washing the dress.","e1t":"Elbiseyi yıkamadan önce etiketi oku.","e2":"He labeled all the boxes.","e2t":"Tüm kutuları etiketledi."},{"w":"labor / labour","tr":"emek / iş gücü / çalışmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Practical work, especially hard physical work","dt":"Pratik iş, özellikle ağır fiziksel iş","e1":"Manual labor is hard.","e1t":"El emeği (fiziksel çalışma) zordur.","e2":"The cost of labor is increasing.","e2t":"İş gücü maliyeti artıyor."},{"w":"laboratory","tr":"laboratuvar","te":"Noun","tt":"İsim","de":"A room used for scientific research or testing","dt":"Bilimsel araştırma veya test için kullanılan oda","e1":"The samples were sent to the laboratory.","e1t":"Numuneler laboratuvara gönderildi.","e2":"We have a chemistry laboratory at school.","e2t":"Okulda bir kimya laboratuvarımız var."},{"w":"ladder","tr":"merdiven (seyyar)","te":"Noun","tt":"İsim","de":"A piece of equipment used for climbing up something","dt":"Bir şeye tırmanmak için kullanılan ekipman","e1":"He climbed up the ladder to fix the roof.","e1t":"Çatıyı tamir etmek için merdivene tırmandı.","e2":"I need a longer ladder.","e2t":"Daha uzun bir merdivene ihtiyacım var."},{"w":"lately","tr":"son zamanlarda","te":"Adverb","tt":"Zarf","de":"Recently","dt":"Son vakitlerde","e1":"I haven't seen him lately.","e1t":"Onu son zamanlarda görmedim.","e2":"What have you been doing lately?","e2t":"Son zamanlarda neler yapıyorsun?"},{"w":"lateral","tr":"yanal / yan","te":"Adjective","tt":"Sıfat","de":"Relating to the sides","dt":"Yan taraflarla ilgili","e1":"He made a lateral move to another department.","e1t":"Başka bir departmana yatay (yanal) geçiş yaptı.","e2":"Lateral thinking.","e2t":"Yanal düşünme."},{"w":"latter","tr":"ikincisi / sonuncusu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The second of two people or things mentioned","dt":"Bahsedilen iki kişi veya şeyden ikincisi","e1":"Of the two options, I prefer the latter.","e1t":"İki seçenekten ikincisini tercih ederim.","e2":"He chose the latter career path.","e2t":"İkinci kariyer yolunu seçti."},{"w":"launch","tr":"başlatmak / fırlatmak / lansman","te":"Verb/Noun","tt":"Fiil/İsim","de":"To start a new activity or to send a rocket","dt":"Yeni bir faaliyete başlamak veya roket göndermek","e1":"The company will launch a new product next month.","e1t":"Şirket önümüzdeki ay yeni bir ürün piyasaya sürecek.","e2":"The rocket launch was successful.","e2t":"Roket fırlatılışı başarılıydı."},{"w":"laundry","tr":"çamaşır / çamaşırhane","te":"Noun","tt":"İsim","de":"Clothes that need washing or have been washed","dt":"Yıkanması gereken veya yıkanmış kıyafetler","e1":"I have to do the laundry today.","e1t":"Bugün çamaşır yıkamam gerekiyor.","e2":"The laundry is drying outside.","e2t":"Çamaşırlar dışarıda kuruyor."},{"w":"lavish","tr":"savurgan / bol / lüks","te":"Adjective/Verb","tt":"Large in amount and expensive or impressive","de":"Miktar olarak büyük ve pahalı veya etkileyici","dt":"They had a lavish wedding.","e1":"Gösterişli (lüks) bir düğünleri oldu.","e1t":"He is lavish with his praise.","e2":"Övgüsünde cömerttir (bol keseden över).","e2t":""},{"w":"lawful","tr":"yasal / meşru","te":"Adjective","tt":"Sıfat","de":"Allowed or recognized by law","dt":"Yasalarca izin verilen veya tanınan","e1":"It is his lawful right.","e1t":"Bu onun yasal hakkıdır.","e2":"A lawful act.","e2t":"Yasal bir eylem."},{"w":"lawsuit","tr":"dava","te":"Noun","tt":"İsim","de":"A legal complaint brought to a court","dt":"Mahkemeye sunulan yasal şikayet","e1":"They filed a lawsuit against the company.","e1t":"Şirkete dava açtılar.","e2":"The lawsuit lasted for three years.","e2t":"Dava üç yıl sürdü."},{"w":"layout","tr":"düzen / yerleşim","te":"Noun","tt":"İsim","de":"The way in which things are arranged","dt":"Şeylerin düzenlenme biçimi","e1":"I like the layout of this apartment.","e1t":"Bu dairenin yerleşimini seviyorum.","e2":"The page layout is clear.","e2t":"Sayfa düzeni net."},{"w":"leadership","tr":"liderlik","te":"Noun","tt":"İsim","de":"The set of characteristics of a leader","dt":"Bir liderin özellikler seti","e1":"Strong leadership is necessary for success.","e1t":"Başarı için güçlü liderlik gereklidir.","e2":"He is in a leadership position.","e2t":"Liderlik konumundadır."},{"w":"leak","tr":"sızmak / sızıntı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To allow liquid or gas to escape through a hole","dt":"Bir delikten sıvı veya gazın kaçmasına izin vermek","e1":"The pipe is leaking.","e1t":"Boru sızdırıyor.","e2":"There is a gas leak in the kitchen.","e2t":"Mutfakta gaz sızıntısı var."},{"w":"lean","tr":"yaslanmak / eğilmek / yağsız","te":"Verb/Adjective","tt":"To slope in one direction or thin and healthy","de":"Bir yöne eğilmek veya ince ve sağlıklı","dt":"Don't lean against the wall.","e1":"Duvara yaslanma.","e1t":"I prefer lean meat.","e2":"Yağsız eti tercih ederim.","e2t":""},{"w":"leap","tr":"sıçramak / atlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a large jump","dt":"Büyük bir zıplama yapmak","e1":"He leaped over the fence.","e1t":"Çitin üzerinden atladı.","e2":"A giant leap for mankind.","e2t":"İnsanlık için dev bir adım (sıçrama)."},{"w":"learning","tr":"öğrenme / bilgi","te":"Noun","tt":"İsim","de":"The activity of getting knowledge","dt":"Bilgi edinme faaliyeti","e1":"Learning a language takes time.","e1t":"Bir dil öğrenmek zaman alır.","e2":"He is a man of great learning.","e2t":"O büyük bilgi sahibi bir adamdır."},{"w":"lease","tr":"kiralamak (sözleşmeli)","te":"Verb/Noun","tt":"Fiil/İsim","de":"A legal agreement to use property for a time","dt":"Mülkü bir süre kullanmak için yapılan yasal anlaşma","e1":"They decided to lease the office.","e1t":"Ofisi kiralamaya karar verdiler.","e2":"The lease expires next year.","e2t":"Kira sözleşmesi seneye bitiyor."},{"w":"leave out","tr":"dışarıda bırakmak / dahil etmemek","te":"Verb","tt":"Fiil","de":"To not include someone or something","dt":"Birini veya bir şeyi dahil etmemek","e1":"Don't leave me out of the plan.","e1t":"Beni planın dışında bırakma.","e2":"I left out an important detail.","e2t":"Önemli bir detayı atladım (dahil etmedim)."},{"w":"lecturer","tr":"öğretim görevlisi / okutman","te":"Noun","tt":"İsim","de":"Someone who teaches at a college or university","dt":"Kolej veya üniversitede ders veren kişi","e1":"He is a lecturer in history.","e1t":"O bir tarih okutmanıdır.","e2":"The lecturer gave an interesting talk.","e2t":"Öğretim görevlisi ilginç bir konuşma yaptı."},{"w":"legacy","tr":"miras / vasiyet","te":"Noun","tt":"İsim","de":"Money or property left to someone; a result of the past","dt":"Birine bırakılan para veya mülk; geçmişin bir sonucu","e1":"He left a huge legacy to his children.","e1t":"Çocuklarına büyük bir miras bıraktı.","e2":"The war left a legacy of bitterness.","e2t":"Savaş ardında bir acı mirası bıraktı."},{"w":"legend","tr":"efsane","te":"Noun","tt":"İsim","de":"A very old story that may or may not be true","dt":"Doğru olabilen veya olmayabilen çok eski hikaye","e1":"The legend of Robin Hood.","e1t":"Robin Hood efsanesi.","e2":"He is a legend in the world of music.","e2t":"O, müzik dünyasında bir efsanedir."},{"w":"legendary","tr":"efsanevi","te":"Adjective","tt":"Sıfat","de":"Very famous and admired","dt":"Çok ünlü ve hayranlık duyulan","e1":"A legendary football player.","e1t":"Efsanevi bir futbolcu.","e2":"The city is famous for its legendary hospitality.","e2t":"Şehir efsanevi misafirperverliğiyle ünlüdür."},{"w":"legislation","tr":"mevzuat / yasama","te":"Noun","tt":"İsim","de":"A law or set of laws","dt":"Bir yasa veya yasalar seti","e1":"New legislation on safety was passed.","e1t":"Güvenlik üzerine yeni mevzuat kabul edildi.","e2":"The government is planning new legislation.","e2t":"Hükümet yeni yasama planlıyor."},{"w":"legitimate","tr":"yasal / meşru","te":"Adjective","tt":"Sıfat","de":"Allowed by law or reasonable","dt":"Yasalarca izin verilen veya makul","e1":"Is this a legitimate business?","e1t":"Bu yasal bir iş mi?","e2":"He has a legitimate reason for being late.","e2t":"Geç kalmak için meşru bir sebebi var."},{"w":"leisure","tr":"boş zaman / hobi","te":"Noun","tt":"İsim","de":"The time when you are not working","dt":"Çalışmadığınız zaman","e1":"What do you do in your leisure time?","e1t":"Boş zamanlarında ne yaparsın?","e2":"Leisure activities include swimming and reading.","e2t":"Boş zaman aktiviteleri yüzme ve okumayı içerir."},{"w":"length","tr":"uzunluk / boy","te":"Noun","tt":"İsim","de":"The measurement of something from end to end","dt":"Bir şeyin uçtan uca ölçümü","e1":"What is the length of the table?","e1t":"Masanın uzunluğu ne kadar?","e2":"The movie is two hours in length.","e2t":"Filmin süresi (uzunluğu) iki saattir."},{"w":"lengthy","tr":"çok uzun / ayrıntılı","te":"Adjective","tt":"Sıfat","de":"Continuing for a long time","dt":"Uzun süre devam eden","e1":"We had a lengthy discussion.","e1t":"Uzun (ayrıntılı) bir tartışma yaptık.","e2":"The process can be quite lengthy.","e2t":"Süreç oldukça uzun olabilir."},{"w":"lens","tr":"mercek / lens","te":"Noun","tt":"İsim","de":"A curved piece of glass or plastic","dt":"Kavisli cam veya plastik parçası","e1":"I need a new lens for my camera.","e1t":"Kameram için yeni bir merceğe ihtiyacım var.","e2":"Contact lenses.","e2t":"Kontakt lensler."},{"w":"lessen","tr":"azaltmak / eksilmek","te":"Verb","tt":"Fiil","de":"To become less in amount or degree","dt":"Miktar veya derece olarak daha az olmak","e1":"The medicine will lessen the pain.","e1t":"İlaç ağrıyı azaltacaktır.","e2":"The noise lessened as they moved away.","e2t":"Onlar uzaklaştıkça gürültü azaldı."},{"w":"lest","tr":"","te":"mesin diye / korkusuyla","tt":"Conjunction","de":"Bağlaç","dt":"For fear that something might happen","e1":"Bir şey olabilir korkusuyla","e1t":"He ran fast lest he should miss the train.","e2":"Treni kaçırmasın diye hızlı koştu.","e2t":"We must be careful lest we fail."},{"w":"let down","tr":"hayal kırıklığına uğratmak","te":"Verb","tt":"Fiil","de":"To disappoint someone by failing to do what was expected","dt":"Bekleneni yapmayarak birini hayal kırıklığına uğratmak","e1":"Please don't let me down.","e1t":"Lütfen beni hayal kırıklığına uğratma.","e2":"I felt let down by the service.","e2t":"Hizmet beni hayal kırıklığına uğrattı."},{"w":"lethal","tr":"ölümcül","te":"Adjective","tt":"Sıfat","de":"Able to cause death","dt":"Ölüme neden olabilen","e1":"A lethal dose of poison.","e1t":"Ölümcül dozda zehir.","e2":"These weapons are lethal.","e2t":"Bu silahlar ölümcüldür."},{"w":"lever","tr":"kaldıraç / kol","te":"Noun/Verb","tt":"İsim/Fiil","de":"A bar or handle used to operate a machine","dt":"Bir makineyi çalıştırmak için kullanılan bar veya kol","e1":"Pull the lever to start the machine.","e1t":"Makineyi başlatmak için kolu çek.","e2":"We used a bar to lever the rock.","e2t":"Kayayı kaldıraçla oynatmak (kaldırmak) için bir bar kullandık."},{"w":"liability","tr":"sorumluluk / yükümlülük","te":"Noun","tt":"İsim","de":"The state of being legally responsible for something","dt":"Bir şeyden yasal olarak sorumlu olma durumu","e1":"The company has no liability for the accident.","e1t":"Şirketin kaza için hiçbir sorumluluğu yoktur.","e2":"His lack of experience is a liability.","e2t":"Deneyim eksikliği bir dezavantajdır (yükümlülüktür)."},{"w":"liable","tr":"sorumlu / meyilli","te":"Adjective","tt":"Sıfat","de":"Legally responsible or likely to do something","dt":"Yasal olarak sorumlu veya bir şeyi yapmaya meyilli","e1":"You are liable for the damage.","e1t":"Hasardan siz sorumlusunuz.","e2":"The bridge is liable to collapse.","e2t":"Köprü çökmeye meyilli (çökebilir)."},{"w":"liberal","tr":"özgürlükçü / cömert / liberal","te":"Adjective","tt":"Sıfat","de":"Respecting different opinions or generous","dt":"Farklı görüşlere saygı duyan veya cömert","e1":"He has liberal views on politics.","e1t":"Siyaset konusunda özgürlükçü görüşleri var.","e2":"She is very liberal with her money.","e2t":"Parası konusunda çok cömerttir."},{"w":"liberty","tr":"özgürlük / hürriyet","te":"Noun","tt":"İsim","de":"The freedom to live as you wish","dt":"İstediğiniz gibi yaşama özgürlüğü","e1":"Statue of Liberty.","e1t":"Özgürlük Anıtı.","e2":"They fought for their liberty.","e2t":"Özgürlükleri için savaştılar."},{"w":"librarian","tr":"kütüphaneci","te":"Noun","tt":"İsim","de":"A person who works in a library","dt":"Kütüphanede çalışan kişi","e1":"Ask the librarian for help.","e1t":"Kütüphaneciden yardım iste.","e2":"He is a professional librarian.","e2t":"O profesyonel bir kütüphanecidir."},{"w":"lick","tr":"yalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move the tongue across something","dt":"Dili bir şeyin üzerinde hareket ettirmek","e1":"The dog licked his hand.","e1t":"Köpek onun elini yaladı.","e2":"He gave the ice cream a lick.","e2t":"Dondurmayı bir yaladı."},{"w":"lid","tr":"kapak","te":"Noun","tt":"İsim","de":"A cover for a container","dt":"Bir kap için örtü","e1":"Put the lid on the pan.","e1t":"Tavanın kapağını kapat.","e2":"I can't open the lid of this jar.","e2t":"Bu kavanozun kapağını açamıyorum."},{"w":"lie down","tr":"uzanmak / yatmak","te":"Verb","tt":"Fiil","de":"To move into a position in which your body is flat","dt":"Vücudun düz olduğu bir konuma geçmek","e1":"I'm going to lie down for a while.","e1t":"Bir süre uzanacağım.","e2":"Lie down on the bed.","e2t":"Yatağa uzan."},{"w":"life expectancy","tr":"yaşam beklentisi","te":"Noun","tt":"İsim","de":"The length of time a person is expected to live","dt":"Bir kişinin yaşaması beklenen sürenin uzunluğu","e1":"Life expectancy has increased in the last century.","e1t":"Yaşam beklentisi son yüzyılda arttı.","e2":"What is the life expectancy in Turkey?","e2t":"Türkiye'deki yaşam beklentisi nedir?"},{"w":"lifetime","tr":"ömür / yaşam boyu","te":"Noun","tt":"İsim","de":"The period of time during which someone is alive","dt":"Birinin hayatta olduğu zaman dilimi","e1":"It was the chance of a lifetime.","e1t":"Ömür boyu bir kez gelecek bir şanstı.","e2":"She spent her lifetime helping others.","e2t":"Ömrünü başkalarına yardım ederek geçirdi."},{"w":"lighten","tr":"hafifletmek / aydınlatmak","te":"Verb","tt":"Fiil","de":"To make something less heavy or brighter","dt":"Bir şeyi daha az ağır veya daha parlak hale getirmek","e1":"The rain began to lighten.","e1t":"Yağmur hafiflemeye başladı.","e2":"This paint will lighten the room.","e2t":"Bu boya odayı aydınlatacak."},{"w":"likewise","tr":"aynı şekilde / keza","te":"Adverb","tt":"Zarf","de":"In the same way","dt":"Aynı biçimde","e1":"Watch him and do likewise.","e1t":"Onu izle ve aynı şekilde yap.","e2":"Nice to meet you.","e2t":"Likewise."},{"w":"limb","tr":"kol / bacak / uzuv","te":"Noun","tt":"İsim","de":"An arm or leg of a person or animal","dt":"İnsan veya hayvanın kolu veya bacağı","e1":"He lost a limb in the accident.","e1t":"Kazada bir uzvunu kaybetti.","e2":"Artificial limbs.","e2t":"Yapay uzuvlar."},{"w":"limitation","tr":"sınırlama / kısıtlama","te":"Noun","tt":"İsim","de":"The act of limiting something or a weak point","dt":"Bir şeyi sınırlama eylemi veya zayıf nokta","e1":"We must accept our limitations.","e1t":"Sınırlarımızı (yetersizliklerimizi) kabul etmeliyiz.","e2":"There is a time limitation for the test.","e2t":"Test için bir zaman sınırlaması var."},{"w":"limited","tr":"sınırlı / kısıtlı","te":"Adjective","tt":"Sıfat","de":"Small in amount or number","dt":"Miktar veya sayıca az","e1":"We have limited time to finish the project.","e1t":"Projeyi bitirmek için sınırlı vaktimiz var.","e2":"This is a limited edition watch.","e2t":"Bu sınırlı üretim bir saattir."},{"w":"limp","tr":"topallamak / aksamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk with difficulty because of an injured leg","dt":"Yaralı bir bacak nedeniyle zorlukla yürümek","e1":"He was limping after the football match.","e1t":"Futbol maçından sonra topallıyordu.","e2":"The dog has a slight limp.","e2t":"Köpeğin hafif bir aksaması var."},{"w":"line up","tr":"sıraya girmek / dizilmek","te":"Verb","tt":"Fiil","de":"To stand in a line or to arrange in a line","dt":"Bir sırada durmak veya sıraya dizmek","e1":"The students lined up for lunch.","e1t":"Öğrenciler öğle yemeği için sıraya girdi.","e2":"Line up the chairs against the wall.","e2t":"Sandalyeleri duvara karşı dizin."},{"w":"linear","tr":"doğrusal","te":"Adjective","tt":"Sıfat","de":"Relating to a straight line","dt":"Düz bir çizgiyle ilgili","e1":"The relationship between the two variables is linear.","e1t":"İki değişken arasındaki ilişki doğrusaldır.","e2":"We need a linear progression.","e2t":"Doğrusal bir ilerlemeye ihtiyacımız var."},{"w":"linger","tr":"oyalanmak / beklemek","te":"Verb","tt":"Fiil","de":"To take a long time to leave or disappear","dt":"Ayrılmak veya kaybolmak için uzun zaman harcamak","e1":"The smell of perfume lingered in the room.","e1t":"Parfüm kokusu odada asılı kaldı (oyalandı).","e2":"We lingered over coffee after dinner.","e2t":"Akşam yemeğinden sonra kahve içerken oyalandık."},{"w":"liquid","tr":"sıvı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance that flows freely, like water","dt":"Su gibi serbestçe akan madde","e1":"Water and oil are liquids.","e1t":"Su ve yağ sıvıdır.","e2":"Liquid soap.","e2t":"Sıvı sabun."},{"w":"literacy","tr":"okuryazarlık","te":"Noun","tt":"İsim","de":"The ability to read and write","dt":"Okuma ve yazma yeteneği","e1":"Computer literacy is essential today.","e1t":"Bilgisayar okuryazarlığı bugün temeldir.","e2":"The adult literacy rate has increased.","e2t":"Yetişkin okuryazarlık oranı arttı."},{"w":"literal","tr":"kelimesi kelimesine / gerçek","te":"Adjective","tt":"Sıfat","de":"The basic or original meaning of a word","dt":"Bir kelimenin temel veya orijinal anlamı","e1":"What is the literal meaning of this phrase?","e1t":"Bu ifadenin kelime anlamı nedir?","e2":"I'm not joking, I'm being literal.","e2t":"Şaka yapmıyorum, gerçek anlamda söylüyorum."},{"w":"literary","tr":"edebi","te":"Adjective","tt":"Sıfat","de":"Relating to literature","dt":"Edebiyatla ilgili","e1":"He won a prestigious literary award.","e1t":"Prestijli bir edebiyat ödülü kazandı.","e2":"I enjoy reading literary classics.","e2t":"Edebi klasikleri okumaktan zevk alırım."},{"w":"litter","tr":"çöp (yere atılan) / yavrular","te":"Noun/Verb","tt":"İsim/Fiil","de":"Small pieces of rubbish left in a public place","dt":"Kamusal alanda bırakılan küçük çöp parçaları","e1":"Don't leave your litter on the beach.","e1t":"Çöpünüzü plajda bırakmayın.","e2":"The cat had a litter of five kittens.","e2t":"Kedinin beş yavrusu oldu (bir batında)."},{"w":"live on","tr":"ile geçinmek / yaşamaya devam etmek","te":"Verb","tt":"Fiil","de":"To use money to buy food and things; to continue existing","dt":"Para ile geçinmek; var olmaya devam etmek","e1":"It's hard to live on a minimum wage.","e1t":"Asgari ücretle geçinmek zordur.","e2":"His memory lives on in our hearts.","e2t":"Hatırası kalplerimizde yaşamaya devam ediyor."},{"w":"livelihood","tr":"geçim / rızık","te":"Noun","tt":"İsim","de":"The money people need to pay for food/housing","dt":"İnsanların yemek/barınma için ihtiyaç duyduğu para","e1":"Farming is their main livelihood.","e1t":"Çiftçilik onların ana geçim kaynağıdır.","e2":"The sea provides a livelihood for the villagers.","e2t":"Deniz, köylüler için bir geçim sağlar."},{"w":"lively","tr":"canlı / hareketli","te":"Adjective","tt":"Sıfat","de":"Full of energy and enthusiasm","dt":"Enerji ve coşku dolu","e1":"The city has a lively nightlife.","e1t":"Şehrin hareketli bir gece hayatı var.","e2":"We had a lively discussion.","e2t":"Canlı bir tartışma yaptık."},{"w":"load","tr":"yük / yüklemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that is carried; to put things into a vehicle","dt":"Taşınan bir şey; bir araca eşya koymak","e1":"The truck is carrying a heavy load.","e1t":"Kamyon ağır bir yük taşıyor.","e2":"Help me load the luggage into the car.","e2t":"Bagajları arabaya yüklememe yardım et."},{"w":"loan","tr":"kredi / ödünç","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money borrowed that must be paid back","dt":"Geri ödenmesi gereken ödünç alınan para","e1":"I took out a loan to buy a house.","e1t":"Ev almak için kredi çektim.","e2":"Can you loan me your pen?","e2t":"Kalemini bana ödünç verebilir misin?"},{"w":"locate","tr":"yerini saptamak / yerleştirmek","te":"Verb","tt":"Fiil","de":"To find or put in a particular place","dt":"Belirli bir yeri bulmak veya oraya koymak","e1":"We are trying to locate the source of the sound.","e1t":"Sesin kaynağını saptamaya (bulmaya) çalışıyoruz.","e2":"The company is located in Istanbul.","e2t":"Şirket İstanbul'da bulunmaktadır."},{"w":"lodge","tr":"kulübe / yerleşmek / saplanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small house in the country; to become stuck","dt":"Kırda küçük ev; bir yere saplanmak","e1":"We stayed at a hunting lodge.","e1t":"Bir avcı kulübesinde kaldık.","e2":"A piece of bone lodged in his throat.","e2t":"Boğazına bir kemik parçası saplandı."},{"w":"logic","tr":"mantık","te":"Noun","tt":"İsim","de":"A particular way of thinking","dt":"Belirli bir düşünme biçimi","e1":"I don't follow your logic.","e1t":"Senin mantığını anlayamıyorum.","e2":"We need to use logic to solve this.","e2t":"Bunu çözmek için mantık kullanmalıyız."},{"w":"logical","tr":"mantıklı","te":"Adjective","tt":"Sıfat","de":"Using sensible reasons","dt":"Makul nedenler kullanan","e1":"It was a logical choice.","e1t":"Mantıklı bir seçimdi.","e2":"There is a logical explanation for this.","e2t":"Bunun için mantıklı bir açıklama var."},{"w":"loneliness","tr":"yalnızlık","te":"Noun","tt":"İsim","de":"The state of being lonely","dt":"Yalnız olma durumu","e1":"Loneliness can be a problem for the elderly.","e1t":"Yalnızlık yaşlılar için bir sorun olabilir.","e2":"He suffered from intense loneliness.","e2t":"Şiddetli yalnızlıktan muzdaripti."},{"w":"long for","tr":"özlemek / can atmak","te":"Verb","tt":"Fiil","de":"To want something very much","dt":"Bir şeyi çok fazla istemek","e1":"I long for a cold drink.","e1t":"Soğuk bir içecek için can atıyorum.","e2":"She longed for her home.","e2t":"Evini özlüyordu."},{"w":"long","tr":"term","te":"uzun vadeli","tt":"Adjective","de":"Sıfat","dt":"Continuing a long time into the future","e1":"Gelecekte uzun süre devam eden","e1t":"We need a long","e2":"term plan.","e2t":"Uzun vadeli bir plana ihtiyacımız var."},{"w":"look after","tr":"bakmak / ilgilenmek","te":"Verb","tt":"Fiil","de":"To take care of someone or something","dt":"Birine veya bir şeye bakmak (ilgi göstermek)","e1":"Who will look after the cat?","e1t":"Kediye kim bakacak?","e2":"I have to look after my little brother.","e2t":"Küçük kardeşime bakmam gerekiyor."},{"w":"look forward to","tr":"dört gözle beklemek","te":"Verb","tt":"Fiil","de":"To feel excited about something in the future","dt":"Gelecekteki bir şey için heyecanlı hissetmek","e1":"I look forward to meeting you.","e1t":"Sizinle tanışmayı dört gözle bekliyorum.","e2":"We are looking forward to our holiday.","e2t":"Tatilimizi dört gözle bekliyoruz."},{"w":"loosen","tr":"gevşetmek","te":"Verb","tt":"Fiil","de":"To make something less tight","dt":"Bir şeyi daha az sıkı hale getirmek","e1":"He loosened his tie.","e1t":"Kravatını gevşetti.","e2":"Loosen the screws before removing the lid.","e2t":"Kapağı çıkarmadan önce vidaları gevşetin."},{"w":"lord","tr":"efendi / bey / senyör","te":"Noun","tt":"İsim","de":"A man of high social rank","dt":"Yüksek sosyal rütbeli adam","e1":"House of Lords.","e1t":"Lordlar Kamarası.","e2":"He lives like a lord.","e2t":"Bir bey/efendi gibi yaşıyor."},{"w":"loss","tr":"kayıp / zarar","te":"Noun","tt":"İsim","de":"The state of no longer having something","dt":"Bir şeye artık sahip olmama durumu","e1":"The company reported a loss this year.","e1t":"Şirket bu yıl zarar bildirdi.","e2":"Hair loss can be stressful.","e2t":"Saç kaybı stresli olabilir."},{"w":"lotion","tr":"losyon","te":"Noun","tt":"İsim","de":"A liquid used on the skin for protection or cleaning","dt":"Ciltte koruma veya temizlik için kullanılan sıvı","e1":"Use suntan lotion before going out.","e1t":"Dışarı çıkmadan önce güneş losyonu kullanın.","e2":"Body lotion makes your skin soft.","e2t":"Vücut losyonu cildinizi yumuşak yapar."},{"w":"lounge","tr":"salon / bekleme odası / yayılmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A public room for waiting or sitting; to relax","dt":"Bekleme veya oturma için halka açık oda; rahatlamak","e1":"We waited in the airport lounge.","e1t":"Havaalanı bekleme salonunda bekledik.","e2":"He was lounging on the sofa.","e2t":"Kanepede yayılmış oturuyordu."},{"w":"lovable","tr":"sevimli / cana yakın","te":"Adjective","tt":"Sıfat","de":"Easy to love","dt":"Sevmesi kolay","e1":"He is a very lovable character.","e1t":"O çok sevimli bir karakterdir.","e2":"A lovable puppy.","e2t":"Cana yakın (sevimli) bir enik."},{"w":"lover","tr":"sevgili / aşık / meraklı","te":"Noun","tt":"İsim","de":"A person you have a romantic relationship with","dt":"Romantik ilişkiniz olan kişi","e1":"He is a nature lover.","e1t":"O bir doğaseverdir.","e2":"They are secret lovers.","e2t":"Onlar gizli sevgililerdir."},{"w":"loyal","tr":"sadık","te":"Adjective","tt":"Sıfat","de":"Always supporting your friends, country, or belief","dt":"Arkadaşlarını, ülkeni veya inancını her zaman destekleyen","e1":"He is a loyal friend.","e1t":"O sadık bir arkadaştır.","e2":"The customers are loyal to the brand.","e2t":"Müşteriler markaya sadıktır."},{"w":"loyalty","tr":"sadakat","te":"Noun","tt":"İsim","de":"The quality of being loyal","dt":"Sadık olma özelliği","e1":"Loyalty is important in a team.","e1t":"Bir takımda sadakat önemlidir.","e2":"Brand loyalty.","e2t":"Marka sadakati."},{"w":"lumber","tr":"kereste / hantalca ilerlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Wood that has been cut into boards","dt":"Tahta olarak kesilmiş odun","e1":"They sell lumber and construction materials.","e1t":"Kereste ve inşaat malzemeleri satıyorlar.","e2":"The truck lumbered down the narrow road.","e2t":"Kamyon dar yolda hantalca ilerledi."},{"w":"luminous","tr":"parlak / ışık saçan","te":"Adjective","tt":"Sıfat","de":"Producing or reflecting bright light","dt":"Parlak ışık üreten veya yansıtan","e1":"The watch has luminous hands.","e1t":"Saatin ışık saçan (parlak) akrep ve yelkovanı var.","e2":"Luminous paint.","e2t":"Fosforlu (parlak) boya."},{"w":"lump","tr":"yumru / parça / topak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of something solid or a swelling","dt":"Katı bir şeyin parçası veya şişlik","e1":"A lump of sugar.","e1t":"Bir küp (parça) şeker.","e2":"He found a lump on his neck.","e2t":"Boynunda bir yumru (şişlik) buldu."},{"w":"lunar","tr":"aya ait","te":"Adjective","tt":"Sıfat","de":"Relating to the moon","dt":"Ay ile ilgili","e1":"A lunar eclipse occurs tonight.","e1t":"Bu gece bir ay tutulması gerçekleşiyor.","e2":"The lunar surface is covered with craters.","e2t":"Ay yüzeyi kraterlerle kaplıdır."},{"w":"lunch break","tr":"öğle arası","te":"Noun","tt":"İsim","de":"The period when you stop work to eat lunch","dt":"Öğle yemeği yemek için işe ara verilen süre","e1":"What time is your lunch break?","e1t":"Öğle aran saat kaçta?","e2":"I read during my lunch break.","e2t":"Öğle aramda kitap okurum."},{"w":"luxury","tr":"lüks","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something expensive that is not necessary","dt":"Gerekli olmayan pahalı şey","e1":"They live in luxury.","e1t":"Lüks içinde yaşıyorlar.","e2":"A luxury hotel.","e2t":"Lüks bir otel."},{"w":"lyric","tr":"şarkı sözü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The words of a song","dt":"Bir şarkının sözleri","e1":"I love the lyrics of this song.","e1t":"Bu şarkının sözlerini seviyorum.","e2":"He is a great lyricist.","e2t":"O harika bir şarkı sözü yazarıdır."},{"w":"machinery","tr":"makine / mekanizma","te":"Noun","tt":"İsim","de":"Machines as a group; a system of parts","dt":"Grup olarak makineler; parçalar sistemi","e1":"Farm machinery is expensive.","e1t":"Tarım makineleri pahalıdır.","e2":"The machinery of government is complex.","e2t":"Hükümet mekanizması karmaşıktır."},{"w":"mad","tr":"deli / kızgın","te":"Adjective","tt":"Sıfat","de":"Mentally ill or very angry","dt":"Zihinsel hasta veya çok kızgın","e1":"Are you mad?","e1t":"Deli misin?","e2":"Don't be mad at me.","e2t":"Bana kızma."},{"w":"magnificent","tr":"muhteşem","te":"Adjective","tt":"Sıfat","de":"Very good, beautiful, or impressive","dt":"Çok iyi, güzel veya etkileyici","e1":"The view from the top is magnificent.","e1t":"Tepeden manzara muhteşemdir.","e2":"A magnificent palace.","e2t":"Muhteşem bir saray."},{"w":"magnitude","tr":"büyüklük / boyut","te":"Noun","tt":"İsim","de":"The large size or importance of something","dt":"Bir şeyin büyük boyutu veya önemi","e1":"We didn't realize the magnitude of the problem.","e1t":"Sorunun büyüklüğünü (boyutunu) fark etmedik.","e2":"The earthquake had a magnitude of 7.0.","e2t":"Depremin büyüklüğü 7.0 idi."},{"w":"maid","tr":"hizmetçi (kadın)","te":"Noun","tt":"İsim","de":"A woman who works in a house or hotel","dt":"Evde veya otelde çalışan kadın","e1":"The maid cleaned the room.","e1t":"Hizmetçi odayı temizledi.","e2":"She works as a maid in a hotel.","e2t":"Bir otelde kat görevlisi (hizmetçi) olarak çalışıyor."},{"w":"mainstream","tr":"ana akım","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Considered normal by most people","dt":"Çoğu insan tarafından normal kabul edilen","e1":"This is a mainstream movie.","e1t":"Bu ana akım (herkese hitap eden) bir filmdir.","e2":"Mainstream media.","e2t":"Ana akım medya."},{"w":"maintenance","tr":"bakım / sürdürme","te":"Noun","tt":"İsim","de":"The work needed to keep something in good condition","dt":"Bir şeyi iyi durumda tutmak için gereken çalışma","e1":"Routine car maintenance is important.","e1t":"Düzenli araba bakımı önemlidir.","e2":"The maintenance of law and order.","e2t":"Kanun ve düzenin sürdürülmesi."},{"w":"majority","tr":"çoğunluk","te":"Noun","tt":"İsim","de":"More than half of a total number","dt":"Toplam sayının yarısından fazlası","e1":"The majority of people agree with the plan.","e1t":"İnsanların çoğunluğu planı onaylıyor.","e2":"She won by a large majority.","e2t":"Büyük bir çoğunlukla kazandı."},{"w":"make up","tr":"telafi etmek / uydurmak / makyaj","te":"Verb/Noun","tt":"Fiil/İsim","de":"To invent a story; to compensate; cosmetics","dt":"Hikaye uydurmak; telafi etmek; kozmetik","e1":"He made up an excuse.","e1t":"Bir bahane uydurdu.","e2":"I need to put on my make","e2t":"up."},{"w":"mandatory","tr":"zorunlu","te":"Adjective","tt":"Sıfat","de":"Something that must be done by law","dt":"Yasalarca yapılması gereken şey","e1":"Attendance at the meeting is mandatory.","e1t":"Toplantıya katılım zorunludur.","e2":"Wearing a seatbelt is mandatory.","e2t":"Emniyet kemeri takmak zorunludur."},{"w":"manifest","tr":"açıkça göstermek / belirgin","te":"Verb/Adjective","tt":"To show something clearly; obvious","de":"Bir şeyi net bir şekilde göstermek; bariz","dt":"His fear manifested itself in his shaking hands.","e1":"Korkusu, titreyen ellerinde kendini açıkça gösterdi.","e1t":"The symptoms of the disease are manifest.","e2":"Hastalığın belirtileri belirgindir.","e2t":""},{"w":"manipulate","tr":"manipüle etmek / yönlendirmek","te":"Verb","tt":"Fiil","de":"To control someone or something in a clever way","dt":"Birini veya bir şeyi zekice bir yolla kontrol etmek (yönlendirmek)","e1":"He knows how to manipulate people to get what he wants.","e1t":"İstediğini elde etmek için insanları nasıl manipüle edeceğini bilir.","e2":"You can manipulate the data to show different results.","e2t":"Farklı sonuçlar göstermek için verileri manipüle edebilirsiniz."},{"w":"manufacture","tr":"üretmek / imalat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce goods in large numbers in a factory","dt":"Fabrikada büyük miktarlarda mal üretmek","e1":"The company manufactures car parts.","e1t":"Şirket araba parçaları üretiyor.","e2":"The manufacture of silk is an ancient art.","e2t":"İpek imalatı antik bir sanattır."},{"w":"manufacturer","tr":"üretici / imalatçı","te":"Noun","tt":"İsim","de":"A company that produces goods","dt":"Mal üreten şirket","e1":"They are the leading manufacturer of mobile phones.","e1t":"Onlar cep telefonlarının önde gelen üreticisidir.","e2":"Contact the manufacturer for repairs.","e2t":"Tamir için üreticiyle iletişime geçin."},{"w":"manuscript","tr":"el yazması","te":"Noun","tt":"İsim","de":"A copy of a book before it is printed","dt":"Bir kitabın basılmadan önceki kopyası","e1":"The library has many ancient manuscripts.","e1t":"Kütüphanede birçok antik el yazması var.","e2":"He is working on his latest manuscript.","e2t":"Son el yazması üzerinde çalışıyor."},{"w":"margin","tr":"kenar boşluğu / kâr payı","te":"Noun","tt":"İsim","de":"The empty space at the side of a page; profit","dt":"Sayfanın yanındaki boş alan; kâr","e1":"Write your notes in the margin.","e1t":"Notlarınızı kenar boşluğuna yazın.","e2":"We are working with a very small profit margin.","e2t":"Çok küçük bir kâr marjıyla çalışıyoruz."},{"w":"marine","tr":"denizle ilgili / denizci","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the sea or sea transport","dt":"Denizle veya deniz taşımacılığıyla ilgili","e1":"He is an expert in marine biology.","e1t":"Deniz biyolojisi konusunda uzmandır.","e2":"The pollution is damaging marine life.","e2t":"Kirlilik deniz yaşamına zarar veriyor."},{"w":"marvelous","tr":"harika / müthiş","te":"Adjective","tt":"Sıfat","de":"Extremely good; wonderful","dt":"Son derece iyi; harika","e1":"We had a marvelous time at the party.","e1t":"Partide harika vakit geçirdik.","e2":"The weather is marvelous today.","e2t":"Bugün hava müthiş."},{"w":"mask","tr":"maske / gizlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A covering for the face or to hide something","dt":"Yüz için örtü veya bir şeyi gizlemek","e1":"He wore a mask to the party.","e1t":"Partiye maske taktı.","e2":"She tried to mask her disappointment with a smile.","e2t":"Hayal kırıklığını bir gülümsemeyle gizlemeye çalıştı."},{"w":"massacre","tr":"katliam / katletmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The killing of many people in a cruel way","dt":"Birçok insanın acımasızca öldürülmesi","e1":"The massacre of innocent civilians.","e1t":"Masum sivillerin katledilmesi.","e2":"Thousands were massacred during the war.","e2t":"Savaş sırasında binlerce kişi katledildi."},{"w":"masterpiece","tr":"başyapıt","te":"Noun","tt":"İsim","de":"A work of art such as a painting that is made with great skill","dt":"Büyük bir beceriyle yapılmış tablo gibi bir sanat eseri","e1":"Leonardo's \"Mona Lisa\" is a masterpiece.","e1t":"Leonardo'nun \"Mona Lisa\"sı bir başyapıttır.","e2":"This book is a literary masterpiece.","e2t":"Bu kitap edebi bir başyapıttır."},{"w":"mature","tr":"olgun / olgunlaşmak","te":"Adjective/Verb","tt":"Behaving like an adult; fully grown","de":"Yetişkin gibi davranan; tamamen büyümüş/gelişmiş","dt":"He is very mature for his age.","e1":"Yaşına göre çok olgun.","e1t":"These trees take years to mature.","e2":"Bu ağaçların olgunlaşması yıllar alır.","e2t":""},{"w":"maturity","tr":"olgunluk","te":"Noun","tt":"İsim","de":"The quality of behaving like an adult","dt":"Yetişkin gibi davranma özelliği","e1":"She showed great maturity in her decision.","e1t":"Kararında büyük bir olgunluk gösterdi.","e2":"The investment reached maturity.","e2t":"Yatırım vadesine (olgunluğa) ulaştı."},{"w":"maximize","tr":"en üst düzeye çıkarmak","te":"Verb","tt":"Fiil","de":"To make something as large as possible","dt":"Bir şeyi mümkün olduğunca büyük/çok yapmak","e1":"We need to maximize our profits.","e1t":"Kârımızı en üst düzeye çıkarmalıyız.","e2":"Maximize the window on the screen.","e2t":"Ekrandaki pencereyi ekranı kaplayacak şekilde büyüt (maximize et)."},{"w":"mayor","tr":"belediye başkanı","te":"Noun","tt":"İsim","de":"The leader of a city or town","dt":"Bir şehrin veya kasabanın lideri","e1":"The mayor announced a new park project.","e1t":"Belediye başkanı yeni bir park projesi duyurdu.","e2":"Who is the mayor of Istanbul?","e2t":"İstanbul'un belediye başkanı kim?"},{"w":"maze","tr":"labirent","te":"Noun","tt":"İsim","de":"A complicated system of paths","dt":"Karmaşık yollar sistemi","e1":"The old city is a maze of narrow streets.","e1t":"Eski şehir dar sokaklardan oluşan bir labirenttir.","e2":"I got lost in the maze.","e2t":"Labirentte kayboldum."},{"w":"meager","tr":"kıt / yetersiz / az","te":"Adjective","tt":"Sıfat","de":"Very small in amount or number","dt":"Miktar veya sayıca çok az","e1":"They survived on a meager income.","e1t":"Kıt bir gelirle hayatta kaldılar.","e2":"A meager meal.","e2t":"Yetersiz (az) bir öğün."},{"w":"meaningful","tr":"anlamlı","te":"Adjective","tt":"Sıfat","de":"Useful, serious, or important","dt":"Yararlı, ciddi veya önemli","e1":"We need to have a meaningful discussion.","e1t":"Anlamlı bir tartışma yapmamız gerekiyor.","e2":"He wants to do something meaningful with his life.","e2t":"Hayatıyla anlamlı bir şeyler yapmak istiyor."},{"w":"means","tr":"araç / yöntem / imkan","te":"Noun","tt":"İsim","de":"A method or way of doing something","dt":"Bir şeyi yapma yöntemi veya yolu","e1":"Television is a means of communication.","e1t":"Televizyon bir iletişim aracıdır.","e2":"He doesn't have the means to buy a car.","e2t":"Araba alacak imkanı (parası) yok."},{"w":"meantime","tr":"bu arada","te":"Noun","tt":"İsim","de":"The time between two events","dt":"İki olay arasındaki zaman","e1":"The doctor will be here soon; in the meantime, try to relax.","e1t":"Doktor yakında burada olacak; bu arada, rahatlamaya çalışın.","e2":"In the meantime, I'll finish my homework.","e2t":"Bu süre zarfında ödevimi bitireceğim."},{"w":"meanwhile","tr":"aynı zamanda / bu sırada","te":"Adverb","tt":"Zarf","de":"While something else is happening","dt":"Başka bir şey olurken","e1":"My mother was cooking; meanwhile, I was seting the table.","e1t":"Annem yemek pişiriyordu; bu sırada ben masayı kuruyordum.","e2":"Meanwhile, back at the office...","e2t":"Bu sırada, ofiste ise..."},{"w":"mechanic","tr":"tamirci / mekanikçi","te":"Noun","tt":"İsim","de":"Someone who repairs machines or cars","dt":"Makineleri veya arabaları tamir eden kişi","e1":"I need to take the car to the mechanic.","e1t":"Arabayı tamirciye götürmem gerekiyor.","e2":"He is a highly skilled mechanic.","e2t":"O çok yetenekli bir tamircidir."},{"w":"mechanical","tr":"mekanik","te":"Adjective","tt":"Sıfat","de":"Relating to machines","dt":"Makinelerle ilgili","e1":"The flight was delayed due to a mechanical problem.","e1t":"Uçuş mekanik bir sorun nedeniyle ertelendi.","e2":"He has a mechanical mind.","e2t":"Mekanik bir zekası (düşünce yapısı) var."},{"w":"mechanism","tr":"mekanizma","te":"Noun","tt":"İsim","de":"A part of a machine or a way of doing something","dt":"Bir makinenin parçası veya bir şeyi yapma yolu","e1":"The locking mechanism is broken.","e1t":"Kilitleme mekanizması bozuk.","e2":"We need a better mechanism for handling complaints.","e2t":"Şikayetleri ele almak için daha iyi bir mekanizmaya ihtiyacımız var."},{"w":"medal","tr":"madalya","te":"Noun","tt":"İsim","de":"A small metal disc given as a reward","dt":"Ödül olarak verilen küçük metal disk","e1":"He won a gold medal in the Olympics.","e1t":"Olimpiyatlarda altın madalya kazandı.","e2":"She was awarded a medal for bravery.","e2t":"Cesaretinden dolayı madalya ile ödüllendirildi."},{"w":"medication","tr":"ilaç tedavisi / ilaç","te":"Noun","tt":"İsim","de":"Medicine used to treat an illness","dt":"Bir hastalığı tedavi etmek için kullanılan ilaç","e1":"Are you taking any medication?","e1t":"Herhangi bir ilaç kullanıyor musun?","e2":"He is on medication for blood pressure.","e2t":"Tansiyon için ilaç tedavisi görüyor."},{"w":"medieval","tr":"ortaçağ / ortaçağa ait","te":"Adjective","tt":"Sıfat","de":"Relating to the Middle Ages (AD 500","dt":"1500)","e1":"Ortaçağ ile ilgili","e1t":"They visited a medieval castle in France.","e2":"Fransa'da ortaçağa ait bir kaleyi ziyaret ettiler.","e2t":"Medieval history."},{"w":"melody","tr":"melodi / ezgi","te":"Noun","tt":"İsim","de":"A tune or a sequence of musical notes","dt":"Bir melodi veya müzik notaları dizisi","e1":"This song has a very beautiful melody.","e1t":"Bu şarkının çok güzel bir melodisi var.","e2":"I can't get that melody out of my head.","e2t":"O melodi zihnimden çıkmıyor."},{"w":"melt","tr":"erimek / eritmek","te":"Verb","tt":"Fiil","de":"To turn from solid to liquid because of heat","dt":"Isı nedeniyle katıdan sıvıya dönüşmek","e1":"The ice began to melt in the sun.","e1t":"Buz güneşte erimeye başladı.","e2":"Melt the butter in a pan.","e2t":"Tereyağını bir tavada erit."},{"w":"membership","tr":"üyelik","te":"Noun","tt":"İsim","de":"The state of being a member of a group","dt":"Bir grubun üyesi olma durumu","e1":"How much is the annual membership fee?","e1t":"Yıllık üyelik ücreti ne kadar?","e2":"Membership is open to everyone.","e2t":"Üyelik herkese açıktır."},{"w":"memorize","tr":"ezberlemek","te":"Verb","tt":"Fiil","de":"To learn something so that you can remember it exactly","dt":"Bir şeyi tam olarak hatırlayabilmek için öğrenmek","e1":"I need to memorize these vocabulary words.","e1t":"Bu kelimeleri ezberlemem gerekiyor.","e2":"She memorized the entire poem.","e2t":"Şiirin tamamını ezberledi."},{"w":"mend","tr":"tamir etmek / onarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To repair something that is broken or damaged","dt":"Kırık veya hasarlı bir şeyi tamir etmek","e1":"Can you mend this broken toy?","e1t":"Bu kırık oyuncağı tamir edebilir misin?","e2":"It's time to mend our relationship.","e2t":"İlişkimizi onarma zamanı."},{"w":"mental","tr":"zihinsel / akılsal","te":"Adjective","tt":"Sıfat","de":"Relating to the mind","dt":"Zihinle ilgili","e1":"Mental health is as important as physical health.","e1t":"Zihin sağlığı fiziksel sağlık kadar önemlidir.","e2":"He made a mental note of the address.","e2t":"Adresi zihnine not etti."},{"w":"mentality","tr":"zihniyet","te":"Noun","tt":"İsim","de":"A person's particular way of thinking","dt":"Bir kişinin kendine özgü düşünme biçimi","e1":"I don't understand the criminal mentality.","e1t":"Suçlu zihniyetini anlamıyorum.","e2":"We need to change our mentality about recycling.","e2t":"Geri dönüşüm konusundaki zihniyetimizi değiştirmeliyiz."},{"w":"mentor","tr":"akıl hocası / rehber","te":"Noun/Verb","tt":"İsim/Fiil","de":"An experienced person who advises a younger person","dt":"Genç birine tavsiyeler veren deneyimli kişi","e1":"He was a great mentor to me during my early career.","e1t":"Kariyerimin başında bana harika bir akıl hocasıydı.","e2":"She mentors young entrepreneurs.","e2t":"Genç girişimcilere rehberlik ediyor."},{"w":"mercy","tr":"merhamet / şefkat","te":"Noun","tt":"İsim","de":"Kindness shown to someone you have the power to punish","dt":"Cezalandırma gücüne sahip olduğun birine gösterilen nezaket","e1":"He begged for mercy.","e1t":"Merhamet için yalvardı.","e2":"The judge showed no mercy.","e2t":"Yargıç hiç merhamet göstermedi."},{"w":"mere","tr":"sadece / sırf","te":"Adjective","tt":"Sıfat","de":"Used to emphasize that something is small or unimportant","dt":"Bir şeyin küçük veya önemsiz olduğunu vurgulamak için kullanılır","e1":"It costs a mere 5 dollars.","e1t":"Sadece 5 dolar tutuyor.","e2":"The mere thought of it makes me happy.","e2t":"Sırf onu düşünmek bile beni mutlu ediyor."},{"w":"merge","tr":"birleşmek / birleştirmek","te":"Verb","tt":"Fiil","de":"To combine to form a single thing","dt":"Tek bir şey oluşturmak için birleşmek","e1":"The two companies decided to merge.","e1t":"İki şirket birleşmeye karar verdi.","e2":"The small stream merges with the river.","e2t":"Küçük dere nehirle birleşiyor."},{"w":"merit","tr":"erdem / hak etmek / başarı","te":"Noun/Verb","tt":"İsim/Fiil","de":"The quality of being good and deserving praise","dt":"İyi olma ve övgüyü hak etme özelliği","e1":"We should judge people on their own merits.","e1t":"İnsanları kendi başarılarına (yeteneklerine) göre değerlendirmeliyiz.","e2":"The idea has some merit.","e2t":"Fikrin bazı iyi yönleri (erdemleri) var."},{"w":"mess","tr":"dağınıklık / karışıklık","te":"Noun/Verb","tt":"İsim/Fiil","de":"An untidy or dirty place or situation","dt":"Düzensiz veya kirli yer veya durum","e1":"Clean up this mess!","e1t":"Bu dağınıklığı temizle!","e2":"The room was in a terrible mess.","e2t":"Oda berbat bir dağınıklık içindeydi."},{"w":"messy","tr":"dağınık / karışık","te":"Adjective","tt":"Sıfat","de":"Untidy or dirty","dt":"Düzensiz veya kirli","e1":"He is a very messy eater.","e1t":"Çok dağınık yemek yiyen biridir.","e2":"My desk is always messy.","e2t":"Masam her zaman dağınıktır."},{"w":"metabolism","tr":"metabolizma","te":"Noun","tt":"İsim","de":"The chemical processes in the body for energy","dt":"Vücuttaki enerji için gerçekleşen kimyasal süreçler","e1":"He has a very fast metabolism.","e1t":"Çok hızlı bir metabolizması var.","e2":"Exercise speeds up your metabolism.","e2t":"Egzersiz metabolizmanızı hızlandırır."},{"w":"metaphor","tr":"metafor / mecaz","te":"Noun","tt":"İsim","de":"A way of describing something by comparing it to something else","dt":"Bir şeyi başka bir şeyle karşılaştırarak tarif etme yolu","e1":"\"Life is a journey\" is a famous metaphor.","e1t":"\"Hayat bir yolculuktur\" ünlü bir metafordur.","e2":"He uses a lot of metaphors in his poetry.","e2t":"Şiirlerinde çok fazla metafor kullanır."},{"w":"methodology","tr":"metodoloji / yöntem bilimi","te":"Noun","tt":"İsim","de":"A system of methods used in a particular activity","dt":"Belirli bir faaliyette kullanılan yöntemler sistemi","e1":"We need to change our research methodology.","e1t":"Araştırma metodolojimizi değiştirmeliyiz.","e2":"What is the methodology of this study?","e2t":"Bu çalışmanın yöntemi nedir?"},{"w":"metropolitan","tr":"büyükşehir / metropol","te":"Adjective","tt":"Sıfat","de":"Relating to a large city","dt":"Büyük bir şehirle ilgili","e1":"The metropolitan area has over ten million people.","e1t":"Büyükşehir bölgesi on milyondan fazla insana sahip.","e2":"Metropolitan police.","e2t":"Büyükşehir polisi."},{"w":"micro","tr":"mikro / çok küçük","te":"Adjective","tt":"Sıfat","de":"Extremely small","dt":"Aşırı derecede küçük","e1":"We are studying micro","e1t":"organisms.","e2":"Mikroorganizmaları inceliyoruz.","e2t":"A micro"},{"w":"microphone","tr":"mikrofon","te":"Noun","tt":"İsim","de":"A piece of equipment used to record or amplify sound","dt":"Sesi kaydetmek veya yükseltmek için kullanılan ekipman","e1":"Please speak into the microphone.","e1t":"Lütfen mikrofona konuşun.","e2":"The microphone isn't working.","e2t":"Mikrofon çalışmıyor."},{"w":"midday","tr":"öğle vakti","te":"Noun","tt":"İsim","de":"Twelve o'clock in the middle of the day","dt":"Günün ortasındaki saat on iki","e1":"We'll meet at midday.","e1t":"Öğlen buluşacağız.","e2":"The midday sun was very hot.","e2t":"Öğle güneşi çok sıcaktı."},{"w":"midst","tr":"orta / aralık","te":"Noun","tt":"İsim","de":"The middle of a group of people or things","dt":"Bir grup insanın veya şeyin ortası","e1":"He was in the midst of the crowd.","e1t":"Kalabalığın ortasındaydı.","e2":"We are in the midst of a crisis.","e2t":"Bir krizin ortasındayız."},{"w":"migrate","tr":"göç etmek","te":"Verb","tt":"Fiil","de":"To move from one place to another, especially animals","dt":"Bir yerden başka yere taşınmak, özellikle hayvanlar","e1":"Birds migrate south in winter.","e1t":"Kuşlar kışın güneye göç ederler.","e2":"Many people migrate to find better jobs.","e2t":"Birçok kişi daha iyi iş bulmak için göç ediyor."},{"w":"migration","tr":"göç","te":"Noun","tt":"İsim","de":"The process of moving from one place to another","dt":"Bir yerden başka bir yere taşınma süreci","e1":"The seasonal migration of birds is fascinating.","e1t":"Kuşların mevsimlik göçü büyüleyicidir.","e2":"Rural","e2t":"to"},{"w":"mild","tr":"hafif / yumuşak / ılıman","te":"Adjective","tt":"Sıfat","de":"Not severe, strong, or serious","dt":"Şiddetli, güçlü veya ciddi olmayan","e1":"We had a very mild winter this year.","e1t":"Bu yıl çok yumuşak bir kış geçirdik.","e2":"I prefer mild curry.","e2t":"Hafif (acısız) köriyi tercih ederim."},{"w":"military","tr":"askeri / ordu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the army","dt":"Orduyla ilgili","e1":"He spent twenty years in the military.","e1t":"Yirmi yılını orduda (askeriyede) geçirdi.","e2":"Military spending has increased.","e2t":"Askeri harcamalar arttı."},{"w":"millennium","tr":"bin yıl","te":"Noun","tt":"İsim","de":"A period of one thousand years","dt":"Bin yıllık zaman dilimi","e1":"The beginning of a new millennium.","e1t":"Yeni bir milenyumun (bin yılın) başlangıcı.","e2":"These ruins are over a millennium old.","e2t":"Bu kalıntılar bin yıldan daha eski."},{"w":"mindset","tr":"düşünce yapısı / zihniyet","te":"Noun","tt":"İsim","de":"A person's way of thinking and their opinions","dt":"Bir kişinin düşünme biçimi ve görüşleri","e1":"We need to change our mindset about energy.","e1t":"Enerji konusundaki düşünce yapımızı değiştirmeliyiz.","e2":"Success requires a positive mindset.","e2t":"Başarı olumlu bir zihniyet gerektirir."},{"w":"mining","tr":"madencilik","te":"Noun","tt":"İsim","de":"The industry of getting coal or minerals from the ground","dt":"Kömür veya madenleri yerden çıkarma endüstrisi","e1":"Coal mining is a dangerous job.","e1t":"Kömür madenciliği tehlikeli bir iştir.","e2":"The local economy depends on mining.","e2t":"Yerel ekonomi madenciliğe dayanıyor."},{"w":"minister","tr":"bakan","te":"Noun","tt":"İsim","de":"A high government official in charge of a department","dt":"Bir departmandan sorumlu yüksek hükümet görevlisi","e1":"The Minister of Education visited our school.","e1t":"Eğitim Bakanı okulumuzu ziyaret etti.","e2":"He was appointed as a government minister.","e2t":"Hükümet bakanı olarak atandı."},{"w":"ministry","tr":"bakanlık","te":"Noun","tt":"İsim","de":"A government department","dt":"Hükümet departmanı","e1":"The Ministry of Foreign Affairs.","e1t":"Dışişleri Bakanlığı.","e2":"He works for the Ministry of Health.","e2t":"Sağlık Bakanlığı için çalışıyor."},{"w":"minority","tr":"azınlık","te":"Noun","tt":"İsim","de":"A small part of a group that is less than half","dt":"Bir grubun yarıdan az olan küçük kısmı","e1":"Only a minority of people voted against the plan.","e1t":"İnsanların sadece azınlığı plana karşı oy kullandı.","e2":"Ethnic minorities in the city.","e2t":"Şehirdeki etnik azınlıklar."},{"w":"miracle","tr":"mucize","te":"Noun","tt":"İsim","de":"An amazing event that is believed to be caused by God","dt":"Tanrı tarafından gerçekleştirildiğine inanılan harika olay","e1":"It was a miracle that they survived the crash.","e1t":"Kazadan sağ kurtulmaları bir mucizeydi.","e2":"The doctor performed a miracle.","e2t":"Doktor bir mucize yarattı."},{"w":"miraculous","tr":"mucizevi","te":"Adjective","tt":"Sıfat","de":"Very surprising or like a miracle","dt":"Çok şaşırtıcı veya mucize gibi","e1":"He made a miraculous recovery.","e1t":"Mucizevi bir iyileşme gösterdi.","e2":"The view was miraculous.","e2t":"Manzara mucizeviydi."},{"w":"miserable","tr":"perişan / mutsuz / berbat","te":"Adjective","tt":"Sıfat","de":"Very unhappy or of very low quality","dt":"Çok mutsuz veya çok düşük kaliteli","e1":"The weather was miserable all weekend.","e1t":"Tüm hafta sonu hava berbattı.","e2":"He felt miserable after losing his job.","e2t":"İşini kaybettikten sonra kendini perişan hissetti."},{"w":"misfortune","tr":"talihsizlik / şanssızlık","te":"Noun","tt":"İsim","de":"Bad luck","dt":"Kötü şans","e1":"He had the misfortune to break his leg.","e1t":"Bacağını kırma talihsizliğini yaşadı.","e2":"We should learn from our misfortunes.","e2t":"Talihsizliklerimizden ders çıkarmalıyız."},{"w":"mislead","tr":"yanlış yönlendirmek / yanıltmak","te":"Verb","tt":"Fiil","de":"To cause someone to believe something that is not true","dt":"Birinin doğru olmayan bir şeye inanmasına neden olmak","e1":"The advertisement was designed to mislead consumers.","e1t":"Reklam tüketicileri yanıltmak için tasarlanmıştı.","e2":"I'm sorry, I didn't mean to mislead you.","e2t":"Üzgünüm, seni yanlış yönlendirmek istememiştim."},{"w":"mission","tr":"görev / misyon","te":"Noun","tt":"İsim","de":"An important job that someone is sent to do","dt":"Birinin yapması için gönderildiği önemli iş","e1":"Their mission was to provide food for the refugees.","e1t":"Görevleri mültecilere yiyecek sağlamaktır.","e2":"The space mission was a success.","e2t":"Uzay görevi bir başarıydı."},{"w":"mist","tr":"sis / duman","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin fog that makes it difficult to see","dt":"Görmeyi zorlaştıran ince sis","e1":"The mountain was covered in mist.","e1t":"Dağ sisle kaplıydı.","e2":"The windows misted up because of the heat.","e2t":"Sıcak nedeniyle camlar buğulandı (sis gibi oldu)."},{"w":"mistaken","tr":"hatalı / yanılmış","te":"Adjective","tt":"Sıfat","de":"Wrong in what you believe or think","dt":"İnandığın veya düşündüğünde yanılmış olma","e1":"If you think I'm paying, you're mistaken.","e1t":"Ödeyeceğimi sanıyorsan yanılıyorsun.","e2":"He had a mistaken idea of the situation.","e2t":"Durum hakkında yanlış bir fikri vardı."},{"w":"misunderstand","tr":"yanlış anlamak","te":"Verb","tt":"Fiil","de":"To fail to understand someone or something correctly","dt":"Birini veya bir şeyi doğru anlamayı başaramamak","e1":"I misunderstood the instructions.","e1t":"Talimatları yanlış anladım.","e2":"Don't misunderstand me; I like your work.","e2t":"Beni yanlış anlama; işini beğeniyorum."},{"w":"misunderstanding","tr":"yanlış anlaşılma","te":"Noun","tt":"İsim","de":"A failure to understand something correctly","dt":"Bir şeyi doğru anlama konusundaki başarısızlık","e1":"There was a misunderstanding about the time.","e1t":"Saat konusunda bir yanlış anlaşılma vardı.","e2":"We need to clear up this misunderstanding.","e2t":"Bu yanlış anlaşılmayı gidermeliyiz."},{"w":"mixture","tr":"karışım","te":"Noun","tt":"İsim","de":"A substance made from mixing other substances","dt":"Diğer maddelerin karıştırılmasıyla oluşan madde","e1":"Add the flour to the mixture.","e1t":"Unu karışıma ekleyin.","e2":"The city is a mixture of old and new.","e2t":"Şehir eski ve yeninin bir karışımıdır."},{"w":"mobile","tr":"mobil / taşınabilir / hareketli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to move or be moved easily","dt":"Kolayca hareket edebilen veya taşınabilen","e1":"He is not very mobile after the surgery.","e1t":"Ameliyattan sonra pek hareketli değil.","e2":"Mobile phone.","e2t":"Cep telefonu."},{"w":"mobility","tr":"hareketlilik / mobilite","te":"Noun","tt":"İsim","de":"The ability to move freely or easily","dt":"Özgürce veya kolayca hareket etme yeteneği","e1":"Many elderly people have limited mobility.","e1t":"Birçok yaşlı insanın hareket kabiliyeti sınırlıdır.","e2":"Upward social mobility.","e2t":"Yukarı doğru sosyal hareketlilik."},{"w":"mock","tr":"alay etmek / sahte (deneme)","te":"Verb/Adjective","tt":"To laugh at someone in an unkind way; not real","de":"Birine kaba bir şekilde gülmek; gerçek olmayan","dt":"They mocked his accent.","e1":"Onun aksanıyla alay ettiler.","e1t":"A mock exam (practice exam).","e2":"Deneme sınavı.","e2t":""},{"w":"mode","tr":"tarz / biçim / mod","te":"Noun","tt":"İsim","de":"A particular way of doing something","dt":"Bir şeyi yapmanın kendine özgü yolu","e1":"Switch the phone to silent mode.","e1t":"Telefonu sessiz moda al.","e2":"A fast mode of transport.","e2t":"Hızlı bir ulaşım biçimi."},{"w":"moderate","tr":"ılımlı / orta karar","te":"Adjective/Noun/Verb","tt":"Neither very small nor very large; not extreme","de":"Ne çok az ne çok fazla; aşırı olmayan","dt":"He has moderate views.","e1":"Ilımlı görüşleri var.","e1t":"We had moderate success.","e2":"Orta karar bir başarı elde ettik.","e2t":""},{"w":"modify","tr":"değiştirmek / modifiye etmek","te":"Verb","tt":"Fiil","de":"To change something slightly to improve it","dt":"Bir şeyi geliştirmek için hafifçe değiştirmek","e1":"We need to modify the plan.","e1t":"Planı değiştirmemiz (güncellememiz) gerekiyor.","e2":"He modified his car.","e2t":"Arabasını modifiye etti."},{"w":"module","tr":"modül / birim","te":"Noun","tt":"İsim","de":"A separate part of a course or machine","dt":"Bir kursun veya makinenin ayrı bir parçası","e1":"I'm studying the marketing module this term.","e1t":"Bu dönem pazarlama modülünü çalışıyorum.","e2":"The lunar module.","e2t":"Ay modülü."},{"w":"moist","tr":"nemli / rutubetli","te":"Adjective","tt":"Sıfat","de":"Slightly wet","dt":"Hafifçe ıslak","e1":"The cake is soft and moist.","e1t":"Kek yumuşak ve nemli.","e2":"Keep the soil moist.","e2t":"Toprağı nemli tutun."},{"w":"moisture","tr":"nem / rutubet","te":"Noun","tt":"İsim","de":"Very small drops of water in the air or on a surface","dt":"Havada veya bir yüzeyde bulunan çok küçük su damlaları","e1":"The plants absorb moisture from the air.","e1t":"Bitkiler nemi havadan emer.","e2":"Moisture in the walls can cause mold.","e2t":"Duvarlardaki nem küfe neden olabilir."},{"w":"mole","tr":"köstebek / ben (vücutta) / molekül","te":"Noun","tt":"İsim","de":"A small animal or a dark spot on the skin","dt":"Küçük bir hayvan veya ciltteki koyu leke","e1":"He has a mole on his right cheek.","e1t":"Sağ yanağında bir ben var.","e2":"The mole dug a hole in the garden.","e2t":"Köstebek bahçede bir delik kazdı."},{"w":"molecule","tr":"molekül","te":"Noun","tt":"İsim","de":"The simplest unit of a chemical substance","dt":"Bir kimyasal maddenin en basit birimi","e1":"A water molecule consists of hydrogen and oxygen.","e1t":"Bir su molekülü hidrojen ve oksijenden oluşur.","e2":"We are studying complex molecules.","e2t":"Karmaşık molekülleri inceliyoruz."},{"w":"monk","tr":"keşiş / rahip","te":"Noun","tt":"İsim","de":"A member of a religious group of men who live together","dt":"Birlikte yaşayan dini bir erkek grubunun üyesi","e1":"He decided to live his life as a monk.","e1t":"Hayatını bir keşiş olarak yaşamaya karar verdi.","e2":"The monks spend their time in prayer.","e2t":"Keşişler zamanlarını duayla geçirirler."},{"w":"monster","tr":"canavar","te":"Noun","tt":"İsim","de":"A large, frightening, and imaginary creature","dt":"Büyük, korkutucu ve hayali yaratık","e1":"He thought there was a monster under his bed.","e1t":"Yatağının altında bir canavar olduğunu sandı.","e2":"The movie is about a sea monster.","e2t":"Film bir deniz canavarı hakkında."},{"w":"monthly","tr":"aylık","te":"Adjective/Adverb/Noun","tt":"Happening once every month","de":"Ayda bir kez gerçekleşen","dt":"We have a monthly meeting.","e1":"Aylık toplantımız var.","e1t":"I pay my rent monthly.","e2":"Kiramı aylık öderim.","e2t":""},{"w":"monument","tr":"anıt / abide","te":"Noun","tt":"İsim","de":"A building or statue to remember a person or event","dt":"Bir kişiyi veya olayı hatırlamak için yapılan yapı veya heykel","e1":"They built a monument to the war heroes.","e1t":"Savaş kahramanları için bir anıt inşa ettiler.","e2":"An ancient monument.","e2t":"Antik bir anıt."},{"w":"morale","tr":"moral / maneviyat","te":"Noun","tt":"İsim","de":"The amount of confidence and enthusiasm a group has","dt":"Bir grubun sahip olduğu güven ve coşku miktarı","e1":"The team's morale is high after the win.","e1t":"Galibiyetten sonra takımın morali yüksek.","e2":"We need to boost employee morale.","e2t":"Çalışan moralini yükseltmeliyiz."},{"w":"moreover","tr":"dahası / ayrıca","te":"Adverb","tt":"Zarf","de":"In addition to what has just been said","dt":"Az önce söylenenlere ek olarak","e1":"The car is too expensive; moreover, it uses too much fuel.","e1t":"Araba çok pahalı; dahası, çok fazla yakıt tüketiyor.","e2":"He is clever; moreover, he is hardworking.","e2t":"Zekidir; ayrıca çalışkandır."},{"w":"mortgage","tr":"ipotek / ev kredisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"An agreement to borrow money to buy a house","dt":"Ev almak için borç para alma anlaşması","e1":"We took out a mortgage to buy the apartment.","e1t":"Daireyi almak için ipotek (ev kredisi) çektik.","e2":"I'm still paying off the mortgage.","e2t":"Hala ev kredisini ödüyorum."},{"w":"motion","tr":"hareket / önerge","te":"Noun/Verb","tt":"İsim/Fiil","de":"The act of moving or a formal proposal","dt":"Hareket etme eylemi veya resmi bir teklif","e1":"The laws of motion.","e1t":"Hareket yasaları.","e2":"He made a motion to end the meeting.","e2t":"Toplantıyı bitirmek için bir önerge verdi."},{"w":"motivate","tr":"motive etmek / isteklendirmek","te":"Verb","tt":"Fiil","de":"To make someone want to do something","dt":"Birinin bir şeyi yapmasını istemesini sağlamak","e1":"A good teacher knows how to motivate students.","e1t":"İyi bir öğretmen öğrencileri nasıl motive edeceğini bilir.","e2":"He is motivated by money.","e2t":"Para tarafından motive ediliyor."},{"w":"motivation","tr":"motivasyon / güdü","te":"Noun","tt":"İsim","de":"The reason why you want to do something","dt":"Bir şeyi yapmayı isteme nedenin","e1":"What is your motivation for learning English?","e1t":"İngilizce öğrenme motivasyonun nedir?","e2":"He lacks motivation.","e2t":"Motivasyon eksikliği var."},{"w":"motive","tr":"gerekçe / sebep / dürtü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A reason for doing something","dt":"Bir şeyi yapma sebebi","e1":"The police are looking for a motive for the crime.","e1t":"Polis suç için bir gerekçe (sebep) arıyor.","e2":"He had no selfish motives.","e2t":"Bencilce bir amacı yoktu."},{"w":"mount","tr":"yükselmek / binmek / monte etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To increase or to get on a horse; to fix something","dt":"Artmak veya ata binmek; bir şeyi sabitlemek/kurmak","e1":"The costs began to mount.","e1t":"Maliyetler artmaya (yükselmeye) başladı.","e2":"He mounted his horse and rode away.","e2t":"Atına bindi ve uzaklaştı."},{"w":"mourn","tr":"yas tutmak / yasını tutmak","te":"Verb","tt":"Fiil","de":"To feel great sadness after someone dies","dt":"Biri öldükten sonra büyük üzüntü hissetmek","e1":"They are mourning the death of their leader.","e1t":"Liderlerinin ölümünün yasını tutuyorlar.","e2":"She mourned for her husband for years.","e2t":"Kocası için yıllarca yas tuttu."},{"w":"move","tr":"hareket etmek / taşınmak / hamle","te":"Verb/Noun","tt":"Fiil/İsim","de":"To change position or home; an action","dt":"Konum veya ev değiştirmek; bir eylem","e1":"We are moving to Istanbul next month.","e1t":"Gelecek ay İstanbul'da taşınıyoruz.","e2":"It's your move (in chess).","e2t":"Hamle sırası sende (satrançta)."},{"w":"mow","tr":"biçmek (çim vb.)","te":"Verb","tt":"Fiil","de":"To cut grass using a machine","dt":"Makine kullanarak çim kesmek","e1":"I need to mow the lawn.","e1t":"Çimleri biçmem gerekiyor.","e2":"He was mowing the grass when it started to rain.","e2t":"Yağmur başladığında çimleri biçiyordu."},{"w":"muddle","tr":"karıştırmak / karmaşa","te":"Verb/Noun","tt":"Fiil/İsim","de":"To confuse things or people; a mess","dt":"Şeyleri veya insanları karıştırmak; karmaşa","e1":"Don't muddle the two files.","e1t":"İki dosyayı birbirine karıştırma.","e2":"The whole situation is a muddle.","e2t":"Tüm durum bir karmaşa."},{"w":"municipal","tr":"belediyeye ait / kentsel","te":"Adjective","tt":"Sıfat","de":"Relating to a city or town government","dt":"Şehir veya kasaba yönetimiyle ilgili","e1":"Municipal elections.","e1t":"Belediye seçimleri.","e2":"He works for the municipal council.","e2t":"Belediye meclisi için çalışıyor."},{"w":"mural","tr":"duvar resmi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A large picture painted on a wall","dt":"Duvara yapılmış büyük resim","e1":"The artists painted a beautiful mural on the school wall.","e1t":"Sanatçılar okulun duvarına güzel bir duvar resmi yaptılar.","e2":"Street murals are popular in this city.","e2t":"Bu şehirde sokak duvar resimleri popülerdir."},{"w":"murder","tr":"cinayet / öldürmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The crime of intentionally killing someone","dt":"Birini kasıtlı olarak öldürme suçu","e1":"He was accused of murder.","e1t":"Cinayetle suçlandı.","e2":"The police are investigating the murder.","e2t":"Polis cinayeti araştırıyor."},{"w":"muscle","tr":"kas","te":"Noun","tt":"İsim","de":"A piece of body tissue that produces movement","dt":"Hareketi sağlayan vücut dokusu parçası","e1":"Exercise helps to build muscle.","e1t":"Egzersiz kas yapmaya yardımcı olur.","e2":"He pulled a muscle in his leg.","e2t":"Bacağında bir kas zedelenmesi (çekmesi) yaşadı."},{"w":"mushroom","tr":"mantar / hızla büyümek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of fungus or to grow very quickly","dt":"Bir mantar türü veya çok hızlı büyümek","e1":"I like mushrooms on my pizza.","e1t":"Pizzamda mantarı severim.","e2":"New buildings are mushrooming all over the city.","e2t":"Şehrin her yerinde yeni binalar mantar gibi ürüyor (hızla büyüyor)."},{"w":"mustache / moustache","tr":"bıyık","te":"Noun","tt":"İsim","de":"Hair that grows above the upper lip","dt":"Üst dudağın üzerinde büyüyen kıllar","e1":"He decided to grow a mustache.","e1t":"Bıyık bırakmaya karar verdi.","e2":"He has a thick black mustache.","e2t":"Kalın siyah bir bıyığı var."},{"w":"mutate","tr":"mutasyona uğramak / değişmek","te":"Verb","tt":"Fiil","de":"To change into a new form","dt":"Yeni bir forma dönüşmek","e1":"The virus has mutated into a more dangerous form.","e1t":"Virüs daha tehlikeli bir forma mutasyona uğradı.","e2":"Technology is mutating at a fast pace.","e2t":"Teknoloji hızlı bir tempoda değişiyor (başkalaşıyor)."},{"w":"mutual","tr":"karşılıklı / ortak","te":"Adjective","tt":"Sıfat","de":"Shared by two or more people","dt":"İki veya daha fazla kişi tarafından paylaşılan","e1":"We have a mutual friend.","e1t":"Ortak bir arkadaşımız var.","e2":"Our respect for each other is mutual.","e2t":"Birbirimize olan saygımız karşılıklı."},{"w":"mysterious","tr":"gizemli / esrarengiz","te":"Adjective","tt":"Sıfat","de":"Strange and difficult to understand or explain","dt":"Garip ve anlaması veya açıklaması zor","e1":"A mysterious stranger arrived at the door.","e1t":"Kapıya gizemli bir yabancı geldi.","e2":"She died under mysterious circumstances.","e2t":"Esrarengiz koşullar altında öldü."},{"w":"myth","tr":"efsane / mit / uydurma","te":"Noun","tt":"İsim","de":"An ancient story or a false belief","dt":"Antik bir hikaye veya yanlış bir inanış","e1":"Greek myths are very interesting.","e1t":"Yunan mitleri çok ilginçtir.","e2":"It is a myth that carrots help you see in the dark.","e2t":"Havucun karanlıkta görmenize yardımcı olduğu bir efsanedir (uydurmadır)."},{"w":"naked","tr":"çıplak","te":"Adjective","tt":"Sıfat","de":"Not wearing any clothes","dt":"Hiç kıyafet giymemiş","e1":"The naked eye cannot see bacteria.","e1t":"Çıplak göz bakterileri göremez.","e2":"A naked flame.","e2t":"Açık (çıplak) ateş."},{"w":"namely","tr":"yani / şöylesi / ismen","te":"Adverb","tt":"Zarf","de":"Used to give more exact information","dt":"Daha kesin bilgi vermek için kullanılır","e1":"We have two problems, namely time and money.","e1t":"İki sorunumuz var; yani zaman ve para.","e2":"Only one person survived, namely the pilot.","e2t":"Sadece bir kişi kurtuldu, yani (o da) pilot."},{"w":"nap","tr":"kısa uyku / kestirme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short sleep, especially during the day","dt":"Özellikle gün içinde yapılan kısa uyku","e1":"My grandfather always takes a nap after lunch.","e1t":"Büyükbabam her zaman öğle yemeğinden sonra kestirir.","e2":"I feel much better after a short nap.","e2t":"Kısa bir uykudan sonra kendimi çok daha iyi hissediyorum."},{"w":"nasty","tr":"kaba / iğrenç / kötü","te":"Adjective","tt":"Sıfat","de":"Very bad or unpleasant","dt":"Çok kötü veya hoş olmayan","e1":"He has a nasty habit of biting his nails.","e1t":"Tırnaklarını yemek gibi kötü bir alışkanlığı var.","e2":"That was a nasty thing to say.","e2t":"Söylenen çok kaba bir şeydi."},{"w":"nationwide","tr":"ülke çapında","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Existing or happening in all parts of a country","dt":"Bir ülkenin her yerinde var olan veya gerçekleşen","e1":"The police launched a nationwide search.","e1t":"Polis ülke çapında bir arama başlattı.","e2":"The store has 50 branches nationwide.","e2t":"Mağazanın ülke çapında 50 şubesi var."},{"w":"native","tr":"yerli / ana / doğal","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the place where you were born","dt":"Doğduğunuz yerle ilgili","e1":"English is my native language.","e1t":"İngilizce benim ana dilim.","e2":"Kangaroos are native to Australia.","e2t":"Kangurular Avustralya'ya özgüdür (yerlisidir)."},{"w":"navigation","tr":"navigasyon / gezinme / seyrüsefer","te":"Noun","tt":"İsim","de":"The act of finding the way to a place","dt":"Bir yere giden yolu bulma eylemi","e1":"The boat's navigation system failed.","e1t":"Teknenein navigasyon sistemi bozuldu.","e2":"Website navigation should be easy.","e2t":"Web sitesi navigasyonu (gezinmesi) kolay olmalı."},{"w":"navy","tr":"donanma / lacivert","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The part of the army that fights at sea","dt":"Ordunun denizde savaşan kısmı","e1":"He joined the navy when he was 18.","e1t":"18 yaşındayken donanmaya katıldı.","e2":"She was wearing a navy blue dress.","e2t":"Lacivert bir elbise giyiyordu."},{"w":"nearby","tr":"yakında / yakınlarda","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not far away","dt":"Uzak olmayan","e1":"Is there a pharmacy nearby?","e1t":"Yakınlarda bir eczane var mı?","e2":"They live in a nearby village.","e2t":"Yakındaki bir köyde yaşıyorlar."},{"w":"necessarily","tr":"mutlaka / illa ki","te":"Adverb","tt":"Zarf","de":"Used to say that something is certain","dt":"Bir şeyin kesin olduğunu söylemek için kullanılır","e1":"Expensive clothes are not necessarily better.","e1t":"Pahalı kıyafetler illa ki daha iyi değildir.","e2":"Big doesn't necessarily mean good.","e2t":"Büyük olması mutlaka iyi olduğu anlamına gelmez."},{"w":"necessity","tr":"gereklilik / ihtiyaç","te":"Noun","tt":"İsim","de":"Something that you must have or do","dt":"Sahip olmanız veya yapmanız gereken şey","e1":"Food is a basic necessity of life.","e1t":"Yemek hayatın temel bir gerekliliğidir.","e2":"Is it a necessity to hire more staff?","e2t":"Daha fazla personel almak bir gereklilik mi?"},{"w":"neglect","tr":"ihmal etmek / bakmamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To not give enough care or attention to something","dt":"Bir şeye yeterince özen veya dikkat göstermemek","e1":"He neglected his health for years.","e1t":"Yıllarca sağlığını ihmal etti.","e2":"The building was in a state of neglect.","e2t":"Bina ihmal edilmiş bir durumdaydı (bakımsızdı)."},{"w":"negotiate","tr":"müzakere etmek / görüşmek","te":"Verb","tt":"Fiil","de":"To try to reach an agreement by formal discussion","dt":"Resmi tartışma yoluyla bir anlaşmaya varmaya çalışmak","e1":"We are trying to negotiate a better deal.","e1t":"Daha iyi bir anlaşma için müzakere etmeye çalışıyoruz.","e2":"The government refused to negotiate with the strikers.","e2t":"Hükümet grevdekilerle görüşmeyi reddetti."},{"w":"negotiation","tr":"müzakere / görüşme","te":"Noun","tt":"İsim","de":"The process of discussing something to reach an agreement","dt":"Anlaşmaya varmak için bir şeyi tartışma süreci","e1":"The negotiations lasted for three weeks.","e1t":"Müzakereler üç hafta sürdü.","e2":"Peace negotiations.","e2t":"Barış görüşmeleri."},{"w":"nerve","tr":"sinir / cesaret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tissue in the body or the bravery to do something","dt":"Vücuttaki bir doku veya bir şeyi yapma cesareti","e1":"Optic nerve.","e1t":"Görme siniri.","e2":"It took a lot of nerve to tell the truth.","e2t":"Doğruyu söylemek çok cesaret istedi."},{"w":"neutral","tr":"tarafsız / nötr","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not supporting either side in an argument","dt":"Bir tartışmada hiçbir tarafı desteklemeyen","e1":"Switzerland remained neutral during the war.","e1t":"İsviçre savaş sırasında tarafsız kaldı.","e2":"He has a neutral attitude toward the plan.","e2t":"Plana karşı tarafsız bir tutumu var."},{"w":"newly","tr":"yeni / yeni yapılmış","te":"Adverb","tt":"Zarf","de":"Recently","dt":"Son zamanlarda","e1":"They are a newly married couple.","e1t":"Onlar yeni evli bir çift.","e2":"A newly built house.","e2t":"Yeni inşa edilmiş bir ev."},{"w":"noble","tr":"soylu / asil / erdemli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Moral, brave, or relating to high social rank","dt":"Ahlaklı, cesur veya yüksek sosyal rütbeli","e1":"It was a noble gesture.","e1t":"Asil bir hareketti.","e2":"He comes from a noble family.","e2t":"Soylu bir aileden geliyor."},{"w":"nobody","tr":"hiç kimse","te":"Pronoun","tt":"Zamir","de":"Not anyone","dt":"Hiç kimse","e1":"Nobody knows the answer.","e1t":"Cevabı hiç kimse bilmiyor.","e2":"There was nobody in the room.","e2t":"Odada hiç kimse yoktu."},{"w":"nominate","tr":"aday göstermek","te":"Verb","tt":"Fiil","de":"To officially suggest someone for a prize or a job","dt":"Birini bir ödül veya iş için resmi olarak önermek","e1":"He was nominated for an Oscar.","e1t":"Oscar'a aday gösterildi.","e2":"We nominated her as our representative.","e2t":"Onu temsilcimiz olarak aday gösterdik."},{"w":"nomination","tr":"adaylık / aday gösterme","te":"Noun","tt":"İsim","de":"The act of nominating someone","dt":"Birini aday gösterme eylemi","e1":"Her nomination was a big surprise.","e1t":"Onun adaylığı büyük bir sürpriz oldu.","e2":"There are three nominations for the award.","e2t":"Ödül için üç adaylık (başvuru) var."},{"w":"nominee","tr":"aday (gösterilen kişi)","te":"Noun","tt":"İsim","de":"A person who has been nominated","dt":"Aday gösterilen kişi","e1":"The nominees for the best actor award.","e1t":"En iyi aktör ödülü adayları.","e2":"He is a leading nominee for the position.","e2t":"Pozisyon için önde gelen adaylardan biridir."},{"w":"non","tr":"profit","te":"kâr amacı gütmeyen","tt":"Adjective","de":"Sıfat","dt":"Not intended to make a profit","e1":"Kâr etmeyi amaçlamayan","e1t":"He works for a non","e2":"profit organization.","e2t":"Kâr amacı gütmeyen bir kuruluşta çalışıyor."},{"w":"nonetheless","tr":"yine de / buna rağmen","te":"Adverb","tt":"Zarf","de":"Despite what has just been said","dt":"Az önce söylenene rağmen","e1":"It was raining; nonetheless, we went for a walk.","e1t":"Yağmur yağıyordu; yine de yürüyüşe çıktık.","e2":"The problem is difficult; nonetheless, we must try.","e2t":"Sorun zor; buna rağmen denemeliyiz."},{"w":"nonsense","tr":"saçmalık / anlamsız","te":"Noun","tt":"İsim","de":"Ideas or statements that are not true or sensible","dt":"Doğru veya mantıklı olmayan fikirler veya ifadeler","e1":"Stop talking nonsense!","e1t":"Saçmalamayı kes!","e2":"It's all a load of nonsense.","e2t":"Hepsi koca bir saçmalık."},{"w":"normally","tr":"normalde / genellikle","te":"Adverb","tt":"Zarf","de":"Usually","dt":"Genellikle","e1":"I normally go to bed at 11 PM.","e1t":"Normalde saat 23:00'te yatarım.","e2":"Normally, this process takes three days.","e2t":"Normalde bu süreç üç gün sürer."},{"w":"notable","tr":"dikkate değer / önemli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Important or deserving to be noticed","dt":"Önemli veya fark edilmeyi hak eden","e1":"This is a notable achievement.","e1t":"Bu dikkate değer bir başarıdır.","e2":"There are several notable differences.","e2t":"Birkaç önemli fark var."},{"w":"notion","tr":"düşünce / kavram / fikir","te":"Noun","tt":"İsim","de":"A belief or idea","dt":"İnanç veya fikir","e1":"I have no notion of what he means.","e1t":"Ne demek istediğine dair hiçbir fikrim yok.","e2":"He has a strange notion that everyone hates him.","e2t":"Herkesin kendisinden nefret ettiğine dair garip bir düşüncesi var."},{"w":"nourish","tr":"beslemek / büyütmek","te":"Verb","tt":"Fiil","de":"To provide food or things necessary for growth","dt":"Büyüme için gerekli olan yiyecek veya şeyleri sağlamak","e1":"Good food nourishes the body.","e1t":"İyi yemek vücudu besler.","e2":"She nourished the plants with care.","e2t":"Bitkileri özenle besledi (büyüttü)."},{"w":"nuclear","tr":"nükleer","te":"Adjective","tt":"Sıfat","de":"Relating to the energy produced by splitting atoms","dt":"Atomların parçalanmasıyla üretilen enerjiyle ilgili","e1":"Nuclear power plants produce electricity.","e1t":"Nükleer güç santralleri elektrik üretir.","e2":"A nuclear weapon.","e2t":"Nükleer silah."},{"w":"nude","tr":"çıplak","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not wearing any clothes, especially in art","dt":"Özellikle sanatta hiç kıyafet giymemiş","e1":"A nude painting.","e1t":"Çıplak bir tablo.","e2":"He posed nude for the artist.","e2t":"Sanatçı için çıplak poz verdi."},{"w":"nuisance","tr":"sıkıntı / dert / baş belası","te":"Noun","tt":"İsim","de":"Something or someone that is annoying","dt":"Rahatsız edici olan bir şey veya birisi","e1":"The loud music is a real nuisance.","e1t":"Yüksek sesli müzik gerçek bir karın ağrısı (sıkıntı).","e2":"I'm sorry to be such a nuisance.","e2t":"Bu kadar yük (ayak bağı) olduğum için üzgünüm."},{"w":"numerous","tr":"çok sayıda / pek çok","te":"Adjective","tt":"Sıfat","de":"Many","dt":"Çok","e1":"I have told him numerous times.","e1t":"Ona pek çok kez söyledim.","e2":"Numerous studies have shown that...","e2t":"Çok sayıda çalışma göstermiştir ki..."},{"w":"nurture","tr":"beslemek / geliştirmek / bakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take care of and encourage growth","dt":"Bakmak ve gelişimi teşvik etmek","e1":"We must nurture our young talents.","e1t":"Genç yeteneklerimizi geliştirmeliyiz (beslemeliyiz).","e2":"Parents nurture their children.","e2t":"Ebeveynler çocuklarını büyütür/beslerler."},{"w":"oak","tr":"meşe","te":"Noun","tt":"İsim","de":"A type of large tree or its wood","dt":"Büyük bir ağaç türü veya onun odunu","e1":"The table is made of solid oak.","e1t":"Masa som meşeden yapılmıştır.","e2":"An oak leaf.","e2t":"Bir meşe yaprağı."},{"w":"oath","tr":"yemin / ant","te":"Noun","tt":"İsim","de":"A formal promise to tell the truth","dt":"Doğruyu söylemek için yapılan resmi söz","e1":"He took an oath to tell the truth in court.","e1t":"Mahkemede doğruyu söylemek için yemin etti.","e2":"A broken oath.","e2t":"Bozulmuş bir yemin."},{"w":"obedient","tr":"itaatkâr / söz dinleyen","te":"Adjective","tt":"Sıfat","de":"Doing what you are told to do","dt":"Size söyleneni yapan","e1":"An obedient dog.","e1t":"Söz dinleyen bir köpek.","e2":"She was always an obedient child.","e2t":"O her zaman itaatkâr bir çocuktu."},{"w":"objection","tr":"itiraz","te":"Noun","tt":"İsim","de":"A reason for disagreeing with something","dt":"Bir şeye katılmama nedeni","e1":"I have no objection to your plan.","e1t":"Planına hiçbir itirazım yok.","e2":"Does anyone have any objections?","e2t":"Kimsenin bir itirazı var mı?"},{"w":"oblige","tr":"zorunda bırakmak / iyilik yapmak","te":"Verb","tt":"Fiil","de":"To force someone to do something; to do a favor","dt":"Birini bir şey yapmaya zorlamak; iyilik yapmak","e1":"I was obliged to leave early.","e1t":"Erken ayrılmak zorunda kaldım.","e2":"I am happy to oblige you.","e2t":"Size yardım etmekten (iyilik yapmaktan) memnuniyet duyarım."},{"w":"obscure","tr":"belirsiz / gizlemek / tanınmamış","te":"Adjective/Verb","tt":"Not clear or not well","de":"known","dt":"Net olmayan veya iyi tanınmayan","e1":"His origins remain obscure.","e1t":"Kökeni belirsizliğini koruyor.","e2":"The clouds obscured the sun.","e2t":"Bulutlar güneşi gizledi."},{"w":"observation","tr":"gözlem","te":"Noun","tt":"İsim","de":"The act of watching carefully","dt":"Dikkatlice izleme eylemi","e1":"He is under observation in the hospital.","e1t":"Hastanede gözlem altında tutuluyor.","e2":"Close observation of the birds.","e2t":"Kuşların yakından gözlemlenmesi."},{"w":"obsession","tr":"takıntı / saplantı","te":"Noun","tt":"İsim","de":"Something you think about all the time","dt":"Sürekli düşündüğünüz şey","e1":"Fitness has become an obsession for him.","e1t":"Fit olmak onun için bir saplantı haline geldi.","e2":"He has an obsession with cleanliness.","e2t":"Temizlik takıntısı var."},{"w":"obsolete","tr":"modası geçmiş / eskimiş","te":"Adjective","tt":"Sıfat","de":"No longer used or useful","dt":"Artık kullanılmayan veya yararlı olmayan","e1":"Manual typewriters are now obsolete.","e1t":"Manuel daktilolar artık eskidi (kullanılmıyor).","e2":"The system will soon be obsolete.","e2t":"Sistem yakında işlevsiz kalacak."},{"w":"obstacle","tr":"engel / mani","te":"Noun","tt":"İsim","de":"Something that blocks your way or makes it difficult","dt":"Yolunuzu kapatan veya bir şeyi zorlaştıran şey","e1":"Fear of failure is the biggest obstacle to success.","e1t":"Başarısızlık korkusu, başarının önündeki en büyük engeldir.","e2":"We must overcome all obstacles.","e2t":"Tüm engelleri aşmalıyız."},{"w":"obtain","tr":"elde etmek / edinmek","te":"Verb","tt":"Fiil","de":"To get something, especially by asking or working","dt":"Bir şeyi, özellikle isteyerek veya çalışarak elde etmek","e1":"He managed to obtain a copy of the report.","e1t":"Raporun bir kopyasını elde etmeyi başardı.","e2":"These conditions no longer obtain.","e2t":"Bu koşullar artık geçerli değil (mevcut değil)."},{"w":"obvious","tr":"açık / bariz / belli","te":"Adjective","tt":"Sıfat","de":"Easy to see, recognize, or understand","dt":"Görmesi, tanıması veya anlaması kolay","e1":"It was obvious that she was unhappy.","e1t":"Mutsuz olduğu belliydi.","e2":"There is no obvious solution to the problem.","e2t":"Sorunun bariz bir çözümü yok."},{"w":"occasional","tr":"ara sıra olan / bazen","te":"Adjective","tt":"Sıfat","de":"Happening from time to time","dt":"Zaman zaman gerçekleşen","e1":"I enjoy an occasional trip to the cinema.","e1t":"Ara sıra sinemaya gitmekten zevk alırım.","e2":"We have occasional rain in summer.","e2t":"Yazın ara sıra yağmur yağar."},{"w":"occupy","tr":"işgal etmek / meşgul etmek / yer kaplamak","te":"Verb","tt":"Fiil","de":"To fill a space or time; to take control of a place","dt":"Bir alanı veya zamanı doldurmak; bir yerin kontrolünü ele geçirmek","e1":"The building is occupied by several companies.","e1t":"Bina birkaç şirket tarafından kullanılıyor (işgal ediliyor).","e2":"He occupied himself with reading.","e2t":"Kendini okumakla meşgul etti."},{"w":"occurrence","tr":"olay / vaka / meydana gelme","te":"Noun","tt":"İsim","de":"Something that happens or the act of happening","dt":"Gerçekleşen bir şey veya gerçekleşme eylemi","e1":"Earthquakes are a frequent occurrence in Turkey.","e1t":"Türkiye'de depremler sık rastlanan bir olaydır.","e2":"The occurrence of the disease is rare.","e2t":"Hastalığın görülme sıklığı (meydana gelmesi) nadirdir."},{"w":"odds","tr":"ihtimaller / şans","te":"Noun","tt":"İsim","de":"The probability that something will happen","dt":"Bir şeyin gerçekleşme olasılığı","e1":"The odds of winning the lottery are very low.","e1t":"Piyangoyu kazanma ihtimali çok düşüktür.","e2":"He succeeded against all odds.","e2t":"Tüm imkansızlıklara (ihtimallere) rağmen başardı."},{"w":"odor / odour","tr":"koku","te":"Noun","tt":"İsim","de":"A smell, especially an unpleasant one","dt":"Koku, özellikle hoş olmayan bir koku","e1":"The strong odor of garlic.","e1t":"Güçlü sarımsak kokusu.","e2":"I detected a strange odor in the room.","e2t":"Odada garip bir koku fark ettim."},{"w":"offend","tr":"gücendirmek / incitmek / suç işlemek","te":"Verb","tt":"Fiil","de":"To make someone upset or angry","dt":"Birini üzmek veya kızdırmak","e1":"I didn't mean to offend you.","e1t":"Seni gücendirmek istememişim.","e2":"He was offended by her remarks.","e2t":"Onun sözlerinden incindi."},{"w":"offense / offence","tr":"suç / saldırı / gücendirme","te":"Noun","tt":"İsim","de":"An illegal act or a cause of being upset","dt":"Yasa dışı eylem veya üzülme nedeni","e1":"Driving without a license is a serious offense.","e1t":"Ehliyetsiz araba sürmek ciddi bir suçtur.","e2":"No offense, but I don't like your tie.","e2t":"Üstüne alınma (gücenme) ama kravatını beğenmiyorum."},{"w":"offensive","tr":"saldırgan / aşağılayıcı / iğrenç","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Causing someone to feel upset; a military attack","dt":"Birinin üzülmesine neden olan; askeri saldırı","e1":"His language was very offensive.","e1t":"Dili çok aşağılayıcıydı (saldırgandı).","e2":"The army launched an offensive.","e2t":"Ordu bir saldırı (taarruz) başlattı."},{"w":"offspring","tr":"yavru / döl / evlat","te":"Noun","tt":"İsim","de":"The young of an animal or a person's children","dt":"Bir hayvanın yavrusu veya bir kişinin çocukları","e1":"Animals fight to protect their offspring.","e1t":"Hayvanlar yavrularını korumak için savaşırlar.","e2":"He has four offspring.","e2t":"Dört çocuğu (evladı) var."},{"w":"ointment","tr":"merhem / krem","te":"Noun","tt":"İsim","de":"A thick substance rubbed on the skin as medicine","dt":"İlaç olarak cilde sürülen yoğun madde","e1":"Apply the ointment twice a day.","e1t":"Merhemi günde iki kez uygulayın.","e2":"The doctor prescribed an antiseptic ointment.","e2t":"Doktor antiseptik bir merhem yazdı."},{"w":"old","tr":"fashioned","te":"eski moda / eskimiş","tt":"Adjective","de":"Sıfat","dt":"Not modern or fashionable anymore","e1":"Artık modern veya moda olmayan","e1t":"My grandfather has old","e2":"fashioned views.","e2t":"Büyükbabamın eski moda görüşleri var."},{"w":"olive","tr":"zeytin","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A small green or black fruit used for oil","dt":"Yağ için kullanılan küçük yeşil veya siyah meyve","e1":"I love black olives for breakfast.","e1t":"Kahvaltıda siyah zeytini severim.","e2":"Olive oil is healthy.","e2t":"Zeytinyağı sağlıklıdır."},{"w":"omit","tr":"dahil etmemek / atlamak / çıkarmak","te":"Verb","tt":"Fiil","de":"To fail to include or to leave out","dt":"Dahil etmemek veya dışarıda bırakmak","e1":"You omitted an important detail.","e1t":"Önemli bir detayı atlamışsın.","e2":"Please omit my name from the list.","e2t":"Lütfen adımı listeden çıkarın."},{"w":"on behalf of","tr":"adına / namına","te":"Phrase","tt":"Kalıp İfade","de":"Representing someone else","dt":"Bir başkasını temsil ederek","e1":"I am calling on behalf of my manager.","e1t":"Müdürüm adına arıyorum.","e2":"He accepted the award on behalf of the whole team.","e2t":"Ödülü tüm ekip adına kabul etti."},{"w":"onboard","tr":"uçakta / gemide / bünyesinde","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"On or in a ship, aircraft, or vehicle","dt":"Bir gemi, uçak veya araçta bulunan","e1":"All the passengers are already onboard.","e1t":"Tüm yolcular çoktan uçağa/gemiye bindi.","e2":"We have a great team onboard for this project.","e2t":"Bu proje için bünyemizde (ekibimizde) harika bir takım var."},{"w":"ongoing","tr":"devam eden / süregelen","te":"Adjective","tt":"Sıfat","de":"Continuing to exist or happen","dt":"Var olmaya veya gerçekleşmeye devam eden","e1":"The police have an ongoing investigation.","e1t":"Polisin devam eden bir soruşturması var.","e2":"Ongoing support is necessary.","e2t":"Sürekli (devam eden) destek gereklidir."},{"w":"onset","tr":"başlangıç / hücum","te":"Noun","tt":"İsim","de":"The beginning of something, especially unpleasant","dt":"Bir şeyin, özellikle hoş olmayan bir şeyin başlangıcı","e1":"The onset of winter was early this year.","e1t":"Kışın başlangıcı bu yıl erkendi.","e2":"The rapid onset of the disease.","e2t":"Hastalığın hızlı başlangıcı (belirmesi)."},{"w":"onto","tr":"üzerine / üstüne","te":"Preposition","tt":"Edat","de":"To a position on a surface","dt":"Bir yüzeydeki bir konuma doğru","e1":"The cat jumped onto the table.","e1t":"Kedi masanın üzerine atladı.","e2":"We climbed onto the roof.","e2t":"Çatının üstüne tırmandık."},{"w":"onward","tr":"ileriye doğru / ileri","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Moving forward to a later time or distance","dt":"Daha ileri bir zamana veya mesafeye doğru hareket eden","e1":"The onward journey took two hours.","e1t":"Yolculuğun devamı (ilerisi) iki saat sürdü.","e2":"We must press onward.","e2t":"İleriye (devamına) doğru zorlamalıyız."},{"w":"open","tr":"minded","te":"açık fikirli","tt":"Adjective","de":"Sıfat","dt":"Willing to consider new ideas","e1":"Yeni fikirleri değerlendirmeye istekli","e1t":"He is an open","e2":"minded person.","e2t":"O açık fikirli biridir."},{"w":"operation","tr":"operasyon / ameliyat / faaliyet","te":"Noun","tt":"İsim","de":"An activity or a medical process","dt":"Bir faaliyet veya tıbbi süreç","e1":"The business operation is expanding.","e1t":"İş faaliyetleri genişliyor.","e2":"He underwent a heart operation.","e2t":"Bir kalp ameliyatı geçirdi."},{"w":"operational","tr":"işlevsel / çalışır durumda","te":"Adjective","tt":"Sıfat","de":"Relating to how a system works or ready to use","dt":"Bir sistemin nasıl çalıştığıyla ilgili veya kullanıma hazır","e1":"The new system will be fully operational by Monday.","e1t":"Yeni sistem Pazartesi günü tam olarak işlevsel (çalışır durumda) olacak.","e2":"Operational costs.","e2t":"İşletme maliyetleri."},{"w":"operator","tr":"operatör / işletmeci","te":"Noun","tt":"İsim","de":"A person who operates equipment or a business","dt":"Bir ekipmanı veya işletmeyi kullanan kişi","e1":"He works as a computer operator.","e1t":"Bilgisayar operatörü olarak çalışıyor.","e2":"Telephone operator.","e2t":"Telefon operatörü."},{"w":"opponent","tr":"rakip / muhalif","te":"Noun","tt":"İsim","de":"Someone who you compete against in a game or fight","dt":"Bir oyunda veya kavgada rekabet ettiğiniz kişi","e1":"He defeated his opponent in the final.","e1t":"Finalde rakibini yendi.","e2":"Political opponents.","e2t":"Siyasi rakipler (muhalifler)."},{"w":"oppose","tr":"karşı çıkmak / muhalefet etmek","te":"Verb","tt":"Fiil","de":"To disagree with something or someone","dt":"Bir şeye veya birine katılmamak","e1":"Many people oppose the new law.","e1t":"Birçok kişi yeni yasaya karşı çıkıyor.","e2":"He opposed the plan from the beginning.","e2t":"Plana başından beri karşı çıktı."},{"w":"opposition","tr":"muhalefet / karşıtlık","te":"Noun","tt":"İsim","de":"Disagreement or the group that opposes the government","dt":"Anlaşmazlık veya hükümete karşı olan grup","e1":"The main opposition party.","e1t":"Ana muhalefet partisi.","e2":"There is strong opposition to the project.","e2t":"Projeye karşı güçlü bir muhalefet var."},{"w":"optimistic","tr":"iyimser","te":"Adjective","tt":"Sıfat","de":"Hopeful and confident about the future","dt":"Gelecek hakkında umutlu ve emin","e1":"I am optimistic about the results.","e1t":"Sonuçlar hakkında iyimserim.","e2":"He has an optimistic outlook on life.","e2t":"Hayata karşı iyimser bir bakış açısı var."},{"w":"optional","tr":"isteğe bağlı / seçmeli","te":"Adjective","tt":"Sıfat","de":"Available but not mandatory","dt":"Mevcut ancak zorunlu olmayan","e1":"The use of a seatbelt is not optional.","e1t":"Emniyet kemeri takmak isteğe bağlı değildir.","e2":"English is an optional course this term.","e2t":"Bu dönem İngilizce seçmeli (isteğe bağlı) bir derstir."},{"w":"oral","tr":"sözlü / ağızdan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Spoken or relating to the mouth","dt":"Konuşulan veya ağızla ilgili","e1":"We have an oral exam tomorrow.","e1t":"Yarın sözlü sınavımız var.","e2":"Oral hygiene.","e2t":"Ağız hijyeni."},{"w":"orbit","tr":"yörünge / yörüngede dönmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The path of an object around another object","dt":"Bir nesnenin diğerinin etrafındaki yolu","e1":"The moon is in orbit around the earth.","e1t":"Ay dünya etrafında bir yörüngededir.","e2":"The satellite orbits the planet.","e2t":"Uydu gezegenin yörüngesinde döner."},{"w":"orchestra","tr":"orkestra","te":"Noun","tt":"İsim","de":"A large group of musicians playing together","dt":"Birlikte çalan geniş müzisyen grubu","e1":"The symphony orchestra performed beautifully.","e1t":"Senfoni orkestrası harika bir performans sergiledi.","e2":"He plays the violin in an orchestra.","e2t":"Bir orkestrada keman çalıyor."},{"w":"organic","tr":"organik","te":"Adjective","tt":"Sıfat","de":"Produced without chemicals; relating to living things","dt":"Kimyasal kullanılmadan üretilmiş; canlılarla ilgili","e1":"I prefer organic vegetables.","e1t":"Organik sebzeleri tercih ederim.","e2":"Organic chemistry.","e2t":"Organik kimya."},{"w":"organism","tr":"organizma / canlı","te":"Noun","tt":"İsim","de":"A single living thing, such as an animal or plant","dt":"Hayvan veya bitki gibi tek bir canlı varlık","e1":"Bacteria are single","e1t":"celled organisms.","e2":"Bakteriler tek hücreli organizmalardır.","e2t":"Every living organism needs water."},{"w":"orientation","tr":"yönelim / uyumlanma / oryantasyon","te":"Noun","tt":"İsim","de":"Direction or training for a new situation","dt":"Yön veya yeni bir durum için eğitim","e1":"The company provides an orientation program for new employees.","e1t":"Şirket yeni çalışanlar için bir oryantasyon programı sağlıyor.","e2":"Sexual orientation.","e2t":"Cinsel yönelim."},{"w":"originally","tr":"başlangıçta / aslen","te":"Adverb","tt":"Zarf","de":"At the beginning or in the first place","dt":"Başlangıçta veya ilk etapta","e1":"The house was originally built in 1920.","e1t":"Ev aslen (başlangıçta) 1920'de inşa edildi.","e2":"I am originally from Trabzon.","e2t":"Ben aslen Trabzonluyum."},{"w":"ornament","tr":"süs / bezek / süslemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object used for decoration","dt":"Dekorasyon için kullanılan nesne","e1":"The Christmas tree was covered with ornaments.","e1t":"Noel ağacı süslerle kaplıydı.","e2":"An architectural ornament.","e2t":"Mimari bir bezeme (süs)."},{"w":"orphan","tr":"yetim / öksüz","te":"Noun/Verb/Adjective","tt":"A child whose parents are dead","de":"Ebeveynleri ölmüş olan çocuk","dt":"He became an orphan during the war.","e1":"Savaş sırasında yetim kaldı.","e1t":"She runs an orphanage for orphans.","e2":"Yetimler için bir yetimhane işletiyor.","e2t":""},{"w":"outcome","tr":"sonuç / netice","te":"Noun","tt":"İsim","de":"The final result of a situation or process","dt":"Bir durumun veya sürecin nihai sonucu","e1":"We are waiting for the outcome of the meeting.","e1t":"Toplantının sonucunu bekliyoruz.","e2":"The outcome was better than we expected.","e2t":"Sonuç beklediğimizden daha iyiydi."},{"w":"outer","tr":"dış / harici","te":"Adjective","tt":"Sıfat","de":"Relating to the outside part","dt":"Dış kısımla ilgili","e1":"The outer walls are made of brick.","e1t":"Dış duvarlar tuğladan yapılmıştır.","e2":"Outer space.","e2t":"Uzay (dış uzay)."},{"w":"outfit","tr":"kıyafet / takım / ekipman","te":"Noun/Verb","tt":"İsim/Fiil","de":"A set of clothes or equipment","dt":"Bir takım kıyafet veya ekipman","e1":"I need a new outfit for the wedding.","e1t":"Düğün için yeni bir kıyafete ihtiyacım var.","e2":"She bought a skiing outfit.","e2t":"Bir kayak takımı (ekipmanı) satın aldı."},{"w":"outgoing","tr":"dışa dönük / giden / ayrılan","te":"Adjective","tt":"Sıfat","de":"Friendly and energetic; leaving a position","dt":"Arkadaş canlısı ve enerjik; bir pozisyondan ayrılan","e1":"She has a very outgoing personality.","e1t":"Çok dışa dönük bir kişiliği var.","e2":"The outgoing president.","e2t":"Ayrılan (görevi devreden) başkan."},{"w":"outline","tr":"ana hat / taslak / özetlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short description of the main points","dt":"Ana noktaların kısa açıklaması","e1":"He gave us an outline of the plan.","e1t":"Bize planın ana hatlarını verdi.","e2":"Draw the outline of the map.","e2t":"Haritanın dış hatlarını çiz."},{"w":"outlook","tr":"bakış açısı / görünüm / beklenti","te":"Noun","tt":"İsim","de":"A person's way of thinking; the likely future situation","dt":"Bir kişinin düşünme biçimi; muhtemel gelecek durum","e1":"He has a positive outlook on life.","e1t":"Hayata karşı olumlu bir bakış açısı var.","e2":"The economic outlook is uncertain.","e2t":"Ekonomik beklenti (görünüm) belirsiz."},{"w":"output","tr":"çıktı / üretim","te":"Noun/Verb","tt":"İsim/Fiil","de":"The amount of something produced","dt":"Üretilen şeyin miktarı","e1":"Industrial output has increased by 10%.","e1t":"Sanayi üretimi %10 arttı.","e2":"The computer output.","e2t":"Bilgisayar çıktısı."},{"w":"outstanding","tr":"olağanüstü / seçkin / ödenmemiş","te":"Adjective","tt":"Sıfat","de":"Excellent or not yet paid","dt":"Mükemmel veya henüz ödenmemiş","e1":"He gave an outstanding performance.","e1t":"Olağanüstü bir performans sergiledi.","e2":"There are some outstanding debts.","e2t":"Bazı ödenmemiş borçlar var."},{"w":"overcome","tr":"üstesinden gelmek / yenmek","te":"Verb","tt":"Fiil","de":"To defeat or succeed in dealing with a problem","dt":"Bir sorunu yenmek veya onunla ilgilenmede başarılı olmak","e1":"We must overcome our fears.","e1t":"Korkularımızın üstesinden gelmeliyiz.","e2":"He overcame his illness.","e2t":"Hastalığını yendi."},{"w":"overlook","tr":"göz ardı etmek / tepeden bakmak","te":"Verb","tt":"Fiil","de":"To fail to notice or to have a view of something from above","dt":"Fark etmemek veya bir şeye tepeden bakmak","e1":"I overlooked the mistake in the report.","e1t":"Rapordaki hatayı göz ardı ettim (fark etmedim).","e2":"The hotel room overlooks the sea.","e2t":"Otel odası denize bakıyor (deniz manzaralı)."},{"w":"overseas","tr":"denizaşırı / yurt dışı","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"In, from, or to other countries","dt":"Diğer ülkelerde, ülkelerden veya ülkelere","e1":"He is planning to work overseas.","e1t":"Yurt dışında çalışmayı planlıyor.","e2":"Overseas students.","e2t":"Denizaşırı (yabancı) öğrenciler."},{"w":"owe","tr":"borçlu olmak","te":"Verb","tt":"Fiil","de":"To need to pay or give something to someone","dt":"Birine bir şey ödeme veya verme ihtiyacı duymak","e1":"I owe you ten dollars.","e1t":"Sana on dolar borcum var.","e2":"We owe a lot to our teachers.","e2t":"Öğretmenlerimize çok şey borçluyuz."},{"w":"own up","tr":"itiraf etmek / üstlenmek","te":"Verb","tt":"Fiil","de":"To admit that you have done something wrong","dt":"Yanlış bir şey yaptığını kabul etmek","e1":"No one owned up to breaking the window.","e1t":"Pencereyi kırdığını kimse itiraf etmedi (üstlenmedi).","e2":"You should own up to your mistakes.","e2t":"Hatalarını üstlenmelisin."},{"w":"ownership","tr":"sahiplik / mülkiyet","te":"Noun","tt":"İsim","de":"The state of owning something","dt":"Bir şeye sahip olma durumu","e1":"Private ownership of land.","e1t":"Arazinin özel mülkiyeti.","e2":"The company is under new ownership.","e2t":"Şirket yeni sahiplik (yönetim) altında."},{"w":"oxygen","tr":"oksijen","te":"Noun","tt":"İsim","de":"A colorless gas that is necessary for life","dt":"Yaşam için gerekli olan renksiz gaz","e1":"Humans need oxygen to breathe.","e1t":"İnsanların nefes almak için oksijene ihtiyacı vardır.","e2":"Oxygen masks.","e2t":"Oksijen maskeleri."},{"w":"pace","tr":"hız / tempo / adım","te":"Noun/Verb","tt":"İsim/Fiil","de":"The speed at which someone or something moves","dt":"Birinin veya bir şeyin hareket etme hızı","e1":"He walked at a fast pace.","e1t":"Hızlı bir tempoda yürüdü.","e2":"The technology is changing at a rapid pace.","e2t":"Teknoloji baş döndürücü bir hızla değişiyor."},{"w":"packet","tr":"paket / ambalaj","te":"Noun","tt":"İsim","de":"A small paper or cardboard container","dt":"Küçük kağıt veya karton kap","e1":"A packet of biscuits.","e1t":"Bir paket bisküvi.","e2":"He opened the packet carefully.","e2t":"Paketi dikkatlice açtı."},{"w":"pad","tr":"ped / not defteri / tampon","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of soft material or a number of sheets of paper","dt":"Yumuşak malzeme parçası veya bir dizi kağıt yaprağı","e1":"I need a pad of paper for my notes.","e1t":"Notlarım için bir bloknot (not defteri) lazım.","e2":"A knee pad for protection.","e2t":"Korunma için dizlik (ped)."},{"w":"paddle","tr":"kürek çekmek / kürek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move a small boat through water using a pole","dt":"Bir direk kullanarak küçük bir tekneyi suda hareket ettirmek","e1":"We paddled the canoe across the lake.","e1t":"Kanoyu gölün karşısına kürekle sürdük.","e2":"A ping","e2t":"pong paddle."},{"w":"painful","tr":"acı verici / ağrılı","te":"Adjective","tt":"Sıfat","de":"Causing emotional or physical pain","dt":"Duygusal veya fiziksel acıya neden olan","e1":"Is your arm still painful?","e1t":"Kolun hala ağrıyor mu?","e2":"It was a painful memory.","e2t":"Acı verici bir hatıraydı."},{"w":"pale","tr":"solgun / açık (renk)","te":"Adjective/Verb/Noun","tt":"Having a skin color that is very white; light in color","de":"Çok beyaz bir cilt rengine sahip olma; açık renkli","dt":"You look a bit pale; are you okay?","e1":"Biraz solgun görünüyorsun; iyi misin?","e1t":"A pale blue shirt.","e2":"Açık mavi bir gömlek.","e2t":""},{"w":"palm","tr":"avuç içi / palmiye","te":"Noun","tt":"İsim","de":"The inside part of the hand or a tropical tree","dt":"Elin iç kısmı veya tropikal bir ağaç","e1":"He held the bird in his palm.","e1t":"Kuşu avucunun içinde tuttu.","e2":"There are many palm trees on the beach.","e2t":"Plajda birçok palmiye ağacı var."},{"w":"panel","tr":"pano / panel / jüri","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small group of people or a flat part of a door/wall","dt":"Küçük bir grup insan veya kapı/duvardaki düz parça","e1":"A panel of experts.","e1t":"Uzmanlar paneli (heyeti).","e2":"The control panel of the machine.","e2t":"Makinenin kontrol paneli."},{"w":"panic","tr":"panik yapmak / panik","te":"Verb/Noun","tt":"Fiil/İsim","de":"A sudden strong feeling of fear","dt":"Ani ve güçlü bir korku hissi","e1":"Don't panic; everything is under control.","e1t":"Panik yapma; her şey kontrol altında.","e2":"The news caused a widespread panic.","e2t":"Haberler yaygın bir paniğe neden oldu."},{"w":"panorama","tr":"panorama / geniş manzara","te":"Noun","tt":"İsim","de":"A view of a large area of land","dt":"Geniş bir arazi alanının görünümü","e1":"The hotel balcony offers a beautiful panorama of the city.","e1t":"Otel balkonu şehrin güzel bir panoramik manzarasını sunuyor.","e2":"A panorama of the mountain range.","e2t":"Dağ sırasının panoraması."},{"w":"parade","tr":"geçit töreni","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large formal meeting of people to celebrate","dt":"Kutlama için yapılan geniş resmi toplantı","e1":"There was a military parade in the square.","e1t":"Meydanda bir askeri geçit töreni vardı.","e2":"Victory parade.","e2t":"Zafer geçit töreni."},{"w":"parcel","tr":"paket / koli","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object wrapped in paper, usually to be sent by post","dt":"Kağıda sarılmış, genellikle posta ile gönderilecek nesne","e1":"The parcel arrived this morning.","e1t":"Koli bu sabah ulaştı.","e2":"He wrapped the gift into a small parcel.","e2t":"Hediyeyi küçük bir paket haline getirdi."},{"w":"pardon","tr":"affetmek / bağışlamak / efendim?","te":"Verb/Noun/Interjection","tt":"To forgive someone; used when you haven't heard something","de":"Birini affetmek; bir şeyi duymadığınızda kullanılır","dt":"I beg your pardon?","e1":"Efendim? (Anlayamadım?)","e1t":"The president granted a pardon to the prisoner.","e2":"Başkan mahkuma bir af (bağışlama) çıkardı.","e2t":""},{"w":"particle","tr":"parçacık / tane","te":"Noun","tt":"İsim","de":"An extremely small piece of matter","dt":"Maddenin son derece küçük bir parçası","e1":"Dust particles in the air.","e1t":"Havadaki toz parçacıkları.","e2":"Elementary particles (protons, electrons).","e2t":"Temel parçacıklar."},{"w":"partnership","tr":"ortaklık","te":"Noun","tt":"İsim","de":"An agreement between two or more people/orgs to work together","dt":"İki veya daha fazla kişi/kurumun birlikte çalışmak için yaptığı anlaşma","e1":"The two companies have formed a partnership.","e1t":"İki şirket bir ortaklık kurdu.","e2":"Marriage is a partnership.","e2t":"Evlilik bir ortaklıktır."},{"w":"passage","tr":"geçit / pasaj / koridor","te":"Noun","tt":"İsim","de":"A short part of a book or a long, narrow space","dt":"Kitabın kısa bir bölümü veya uzun, dar bir alan","e1":"He read a passage from the Bible.","e1t":"İncil'den bir pasaj okudu.","e2":"A narrow passage between the buildings.","e2t":"Binalar arasındaki dar geçit."},{"w":"passion","tr":"tutku / hırs","te":"Noun","tt":"İsim","de":"A very strong belief or feeling about something","dt":"Bir şey hakkında çok güçlü inanç veya duygu","e1":"He has a passion for music.","e1t":"Müziğe karşı bir tutkusu var.","e2":"She spoke with passion.","e2t":"Tutkuyla konuştu."},{"w":"passionate","tr":"tutkulu / ateşli","te":"Adjective","tt":"Sıfat","de":"Having or showing very strong feelings","dt":"Çok güçlü duygulara sahip olma veya gösterme","e1":"He is a passionate supporter of the team.","e1t":"Takımın tutkulu bir destekçisidir.","e2":"A passionate kiss.","e2t":"Ateşli bir öpücük."},{"w":"passive","tr":"pasif / edilgen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not acting to influence or change a situation","dt":"Bir durumu etkilemek veya değiştirmek için harekete geçmeyen","e1":"He has a passive personality.","e1t":"Pasif bir kişiliği var.","e2":"Passive smoking (breathing in other people's smoke).","e2t":"Pasif içicilik."},{"w":"paste","tr":"yapıştırmak / macun","te":"Verb/Noun","tt":"Fiil/İsim","de":"To join things together with glue; a thick soft substance","dt":"Şeyleri tutkalla birleştirmek; yoğun yumuşak madde","e1":"Copy and paste the text.","e1t":"Metni kopyala ve yapıştır.","e2":"Toothpaste.","e2t":"Diş macunu."},{"w":"pasture","tr":"otlak / mera","te":"Noun/Verb","tt":"İsim/Fiil","de":"Land covered with grass for animals to eat","dt":"Hayvanların yemesi için çimle kaplı arazi","e1":"The cows are in the pasture.","e1t":"İnekler merada (otlakta).","e2":"We need to protect the natural pastures.","e2t":"Doğal meraları korumalıyız."},{"w":"patch","tr":"yama / yamamak / küçük alan","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small area of something; to repair with a piece of material","dt":"Bir şeyin küçük alanı; bir malzeme parçasıyla tamir etmek","e1":"He has a patch on his jeans.","e1t":"Kotunda bir yama var.","e2":"I found a sunny patch in the garden.","e2t":"Bahçede güneşli bir alan buldum."},{"w":"patience","tr":"sabır","te":"Noun","tt":"İsim","de":"The ability to stay calm and wait","dt":"Sakin kalma ve bekleme yeteneği","e1":"You need a lot of patience to be a teacher.","e1t":"Öğretmen olmak için çok sabra ihtiyacın var.","e2":"My patience is running out.","e2t":"Sabrım tükeniyor."},{"w":"patriot","tr":"vatansever","te":"Noun","tt":"İsim","de":"A person who loves and supports their country","dt":"Ülkesini seven ve destekleyen kişi","e1":"He is a true patriot.","e1t":"O gerçek bir vatanseverdir.","e2":"They are proud patriots.","e2t":"Onlar gururlu vatanseverlerdir."},{"w":"patrol","tr":"devriye gezmek / devriye","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go around a place to check that it is safe","dt":"Güvenli olduğunu kontrol etmek için bir yerin etrafında dolaşmak","e1":"The police patrol the streets at night.","e1t":"Polis gece sokaklarda devriye gezer.","e2":"A border patrol.","e2t":"Sınır devriyesi."},{"w":"pave","tr":"döşemek / kaplamak (yol vb.)","te":"Verb","tt":"Fiil","de":"To cover a surface with flat stones or concrete","dt":"Bir yüzeyi düz taşlar veya betonla kaplamak","e1":"The garden path is paved with stones.","e1t":"Bahçe yolu taşlarla döşeli.","e2":"This discovery paved the way for new treatments.","e2t":"Bu keşif yeni tedavilerin önünü açtı (yolunu döşedi)."},{"w":"pavement","tr":"kaldırım / yol yüzeyi","te":"Noun","tt":"İsim","de":"A path for people to walk on at the side of a road","dt":"Yol kenarında insanların yürümesi için olan patika","e1":"Please walk on the pavement.","e1t":"Lütfen kaldırımda yürüyün.","e2":"The pavement was wet after the rain.","e2t":"Yağmurdan sonra kaldırım ıslaktı."},{"w":"payroll","tr":"maaş bordrosu / çalışan listesi","te":"Noun","tt":"İsim","de":"A list of people employed by a company and their pay","dt":"Şirket tarafından istihdam edilen kişilerin ve maaşlarının listesi","e1":"There are 500 people on the payroll.","e1t":"Maaş listesinde (bordroda) 500 kişi var.","e2":"The payroll department.","e2t":"Maaş (muhasebe) departmanı."},{"w":"peaceful","tr":"huzurlu / barışçıl","te":"Adjective","tt":"Sıfat","de":"Quiet and calm; not involving war or violence","dt":"Sessiz ve sakin; savaş veya şiddet içermeyen","e1":"It was a peaceful morning.","e1t":"Huzurlu bir sabahtı.","e2":"They had a peaceful protest.","e2t":"Barışçıl bir protesto gerçekleştirdiler."},{"w":"peak","tr":"zirve / tepe / en üst nokta","te":"Noun/Verb/Adjective","tt":"The highest point of a mountain or a situation","de":"Bir dağın veya durumun en yüksek noktası","dt":"He reached the peak of the mountain.","e1":"Dağın zirvesine ulaştı.","e1t":"The peak hour for traffic.","e2":"Trafiğin en yoğun (zirve) saati.","e2t":""},{"w":"pedestrian","tr":"yaya","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is walking and not traveling in a vehicle","dt":"Bir araçta seyahat etmeyen, yürüyen kişi","e1":"The street is for pedestrians only.","e1t":"Cadde sadece yayalar içindir.","e2":"Pedestrian crossing.","e2t":"Yaya geçidi."},{"w":"peel","tr":"soymak / kabuk","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove the skin of a fruit or vegetable","dt":"Meyve veya sebzenin kabuğunu çıkarmak","e1":"Peel the potatoes before boiling them.","e1t":"Patatesleri haşlamadan önce soyun.","e2":"Orange peel.","e2t":"Portakal kabuğu."},{"w":"peer","tr":"akran / dikkatle bakmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person of the same age or status; to look carefully","dt":"Aynı yaş veya statüdeki kişi; dikkatlice bakmak","e1":"Peer pressure (pressure from friends).","e1t":"Akran baskısı.","e2":"She peered through the window.","e2t":"Pencereden dikkatle baktı (süzdü)."},{"w":"penalty","tr":"ceza","te":"Noun","tt":"İsim","de":"A punishment for breaking a law or rule","dt":"Bir yasayı veya kuralı bozmanın cezası","e1":"There is a penalty for late payment.","e1t":"Geç ödeme için bir ceza vardır.","e2":"The referee gave a penalty.","e2t":"Hakem penaltı verdi."},{"w":"penetrate","tr":"nüfuz etmek / içine girmek","te":"Verb","tt":"Fiil","de":"To move into or through something","dt":"Bir şeyin içine veya içinden geçmek","e1":"The rain penetrated his clothes.","e1t":"Yağmur kıyafetlerine nüfuz etti (işledi).","e2":"It is difficult to penetrate the thick forest.","e2t":"Sık ormanın içine girmek zordur."},{"w":"peninsula","tr":"yarımada","te":"Noun","tt":"İsim","de":"An area of land surrounded by water on three sides","dt":"Üç tarafı suyla çevrili arazi parçası","e1":"Italy is a peninsula.","e1t":"İtalya bir yarımadadır.","e2":"The Anatolian Peninsula.","e2t":"Anadolu Yarımadası."},{"w":"pension","tr":"emekli maaşı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money paid regularly to a person who has retired","dt":"Emekli olmuş bir kişiye düzenli olarak ödenen para","e1":"He lives on his state pension.","e1t":"Devletten aldığı emekli maaşıyla yaşıyor.","e2":"Private pension plan.","e2t":"Özel emeklilik planı."},{"w":"perceive","tr":"algılamak / fark etmek","te":"Verb","tt":"Fiil","de":"To notice or understand something; to see in a certain way","dt":"Bir şeyi fark etmek veya anlamak; belirli bir şekilde görmek","e1":"I perceived a change in his behavior.","e1t":"Davranışında bir değişiklik algıladım (fark ettim).","e2":"How do you perceive the situation?","e2t":"Durumu nasıl algılıyorsun?"},{"w":"percentage","tr":"yüzde / oran","te":"Noun","tt":"İsim","de":"An amount of something, expressed as a part of 100","dt":"Bir şeyin 100'ün parçası olarak ifade edilen miktarı","e1":"What percentage of the students passed?","e1t":"Öğrencilerin yüzde kaçı geçti?","e2":"A high percentage of the population.","e2t":"Nüfusun yüksek bir oranı."},{"w":"perception","tr":"algı / kavrayış","te":"Noun","tt":"İsim","de":"A belief or opinion often held by many people","dt":"Genellikle birçok kişi tarafından sahip olunan inanç veya görüş","e1":"Public perception of the police.","e1t":"Halkın polis algısı.","e2":"He has a keen perception.","e2t":"Keskin bir kavrayışı (algısı) var."},{"w":"perfection","tr":"mükemmellik","te":"Noun","tt":"İsim","de":"The state of being perfect","dt":"Kusursuz olma durumu","e1":"She strives for perfection in her work.","e1t":"İşinde mükemmellik için çabalıyor.","e2":"The cake was baked to perfection.","e2t":"Kek mükemmel bir şekilde pişmişti."},{"w":"perfume","tr":"parfüm / hoş koku","te":"Noun/Verb","tt":"İsim/Fiil","de":"A liquid with a pleasant smell","dt":"Hoş kokulu sıvı","e1":"She is wearing a sweet perfume.","e1t":"Tatlı bir parfüm sürünmüş.","e2":"The room was perfumed with roses.","e2t":"Oda gül kokuyordu (gül ile kokulandırılmıştı)."},{"w":"perhaps","tr":"belki / muhtemelen","te":"Adverb","tt":"Zarf","de":"Used to show that something is possible","dt":"Bir şeyin mümkün olduğunu göstermek için kullanılır","e1":"Perhaps he is late.","e1t":"Belki gecikmiştir.","e2":"This is perhaps the best movie I've seen.","e2t":"Bu muhtemelen izlediğim en iyi film."},{"w":"peril","tr":"tehlike / risk","te":"Noun/Verb","tt":"İsim/Fiil","de":"Extreme danger","dt":"Aşırı tehlike","e1":"The ship was in great peril.","e1t":"Gemi büyük tehlike altındaydı.","e2":"You do it at your own peril.","e2t":"Bunu riskini göze alarak yapıyorsun."},{"w":"permit","tr":"izin vermek / ruhsat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To allow something to happen; an official document","dt":"Bir şeyin olmasına izin vermek; resmi belge","e1":"Photography is not permitted here.","e1t":"Burada fotoğraf çekilmesine izin verilmez.","e2":"You need a work permit.","e2t":"Çalışma iznine (ruhsatına) ihtiyacın var."},{"w":"persist","tr":"üstelemek / ısrar etmek / sürmek","te":"Verb","tt":"Fiil","de":"To continue to do something despite difficulties","dt":"Zorluklara rağmen bir şeyi yapmaya devam etmek","e1":"If the symptoms persist, see a doctor.","e1t":"Belirtiler sürerse (devam ederse) bir doktora görünün.","e2":"He persisted in his efforts to find a job.","e2t":"İş bulma çabalarında ısrar etti."},{"w":"persistence","tr":"ısrar / kararlılık / süreklilik","te":"Noun","tt":"Isim","de":"The quality of continuing to do something","dt":"Bir şeyi yapmaya devam etme özelliği","e1":"His persistence finally paid off.","e1t":"Kararlılığı sonunda meyvesini verdi.","e2":"The persistence of the problem is worrying.","e2t":"Sorunun sürekliliği endişe verici."},{"w":"persistent","tr":"ısrarcı / kalıcı / inatçı","te":"Adjective","tt":"Sıfat","de":"Lasting for a long time or difficult to stop","dt":"Uzun süre devam eden veya durdurulması zor olan","e1":"She has a persistent cough.","e1t":"Kalıcı (geçmeyen) bir öksürüğü var.","e2":"He is a persistent salesman.","e2t":"O ısrarcı bir satıcıdır."},{"w":"personnel","tr":"personel / çalışanlar","te":"Noun","tt":"Isim","de":"The people who work for an organization","dt":"Bir kuruluş için çalışan insanlar","e1":"All personnel must attend the meeting.","e1t":"Tüm personel toplantıya katılmalıdır.","e2":"The personnel department (HR).","e2t":"Personel departmanı (İK)."},{"w":"perspective","tr":"bakış açısı / perspektif","te":"Noun","tt":"Isim","de":"A particular way of considering something","dt":"Bir şeyi değerlendirmenin özel bir yolu","e1":"You need to keep things in perspective.","e1t":"Olayları doğru bir perspektifte (bakış açısında) tutmalısın.","e2":"From a business perspective, this is a good idea.","e2t":"İş dünyası açısından bakıldığında bu iyi bir fikir."},{"w":"persuade","tr":"ikna etmek / razı etmek","te":"Verb","tt":"Fiil","de":"To make someone do or believe something","dt":"Birinin bir şeyi yapmasını veya inanmasını sağlamak","e1":"I managed to persuade him to come.","e1t":"Onu gelmeye ikna etmeyi başardım.","e2":"He is hard to persuade.","e2t":"Onu ikna etmek zordur."},{"w":"persuasion","tr":"ikna / inanç","te":"Noun","tt":"Isim","de":"The act of persuading someone","dt":"Birini ikna etme eylemi","e1":"It took a lot of persuasion to get him to agree.","e1t":"Onu razı etmek için çok fazla ikna çabası gerekti.","e2":"People of all religious persuasions.","e2t":"Tüm dini inançlardan insanlar."},{"w":"pessimistic","tr":"karamsar / kötümser","te":"Adjective","tt":"Sıfat","de":"Thinking that bad things are more likely to happen","dt":"Kötü şeylerin olma ihtimalinin daha yüksek olduğunu düşünme","e1":"He has a pessimistic view of the future.","e1t":"Geleceğe dair karamsar bir bakış açısı var.","e2":"Don't be so pessimistic!","e2t":"Bu kadar kötümser olma!"},{"w":"pesticide","tr":"tarım ilacı / böcek ilacı","te":"Noun","tt":"Isim","de":"A chemical used for killing pests","dt":"Zararlıları öldürmek için kullanılan kimyasal","e1":"Farmers use pesticides to protect their crops.","e1t":"Çiftçiler mahsullerini korumak için tarım ilacı kullanırlar.","e2":"Pesticide residues in food.","e2t":"Gıdalardaki tarım ilacı kalıntıları."},{"w":"petrol","tr":"benzin","te":"Noun","tt":"Isim","de":"A liquid fuel used in cars","dt":"Arabalarda kullanılan sıvı yakıt","e1":"I need to stop for some petrol.","e1t":"Benzin almak için durmam gerekiyor.","e2":"The price of petrol has gone up.","e2t":"Benzin fiyatı arttı."},{"w":"phase","tr":"aşama / evre / faz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A stage in a series of events","dt":"Bir dizi olaydaki bir aşama","e1":"The project is in its final phase.","e1t":"Proje final aşamasında.","e2":"We are phasing out the old models.","e2t":"Eski modelleri aşamalı olarak kaldırıyoruz."},{"w":"phenomenon","tr":"fenomen / olgu / olay","te":"Noun","tt":"Isim","de":"Something that exists or happens, especially something unusual","dt":"Var olan veya gerçekleşen şey, özellikle sıra dışı bir durum","e1":"Natural phenomena like rainbows.","e1t":"Gökkuşağı gibi doğa olayları (fenomenleri).","e2":"Globalization is a complex phenomenon.","e2t":"Küreselleşme karmaşık bir olgudur."},{"w":"philosophy","tr":"felsefe","te":"Noun","tt":"Isim","de":"The study of the fundamental nature of knowledge","dt":"Bilginin temel doğasının incelenmesi","e1":"He is studying philosophy at university.","e1t":"Üniversitede felsefe okuyor.","e2":"What is your philosophy of life?","e2t":"Hayat felsefen nedir?"},{"w":"physician","tr":"hekim / doktor","te":"Noun","tt":"Isim","de":"A medical doctor","dt":"Tıp doktoru","e1":"You should consult your physician.","e1t":"Hekiminize danışmalısınız.","e2":"He is a distinguished physician.","e2t":"O seçkin bir hekimdir."},{"w":"physics","tr":"fizik","te":"Noun","tt":"Isim","de":"The scientific study of matter and energy","dt":"Madde ve enerjinin bilimsel incelenmesi","e1":"I started my career as a physics teacher.","e1t":"Kariyerime fizik öğretmeni olarak başladım.","e2":"The laws of physics.","e2t":"Fizik yasaları."},{"w":"pillow","tr":"yastık (baş için)","te":"Noun","tt":"Isim","de":"A soft object used to support your head in bed","dt":"Yatakta başınızı desteklemek için kullanılan yumuşak nesne","e1":"I can't sleep without a pillow.","e1t":"Yastıksız uyuyamam.","e2":"Feather pillows are very soft.","e2t":"Tüy yastıklar çok yumuşaktır."},{"w":"pine","tr":"çam / hasret çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of evergreen tree or to miss someone very much","dt":"Bir tür her dem yeşil ağaç veya birini çok özlemek","e1":"The smell of pine trees.","e1t":"Çam ağaçlarının kokusu.","e2":"She was pining for her home.","e2t":"Evi için hasret çekiyordu."},{"w":"pioneer","tr":"öncü / yol açmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who is among the first to do something","dt":"Bir şeyi ilk yapanlar arasında olan kişi","e1":"He was a pioneer in the field of AI.","e1t":"O, yapay zeka alanında bir öncüydü.","e2":"They pioneered new surgical techniques.","e2t":"Yeni cerrahi tekniklere öncülük ettiler."},{"w":"pitch","tr":"saha / zift / perde (ses)","te":"Noun/Verb","tt":"İsim/Fiil","de":"An area painted with lines for playing sports; level of sound","dt":"Spor yapmak için çizgilerle boyanmış alan; ses düzeyi","e1":"A football pitch.","e1t":"Futbol sahası.","e2":"He has a high","e2t":"pitched voice."},{"w":"pity","tr":"acımak / merhamet / yazık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of sadness for someone else's problems","dt":"Başkasının sorunları için duyulan üzüntü hissi","e1":"It's a pity that you can't come.","e1t":"Gelememen ne yazık.","e2":"I pity people who have no homes.","e2t":"Evi olmayan insanlara acıyorum."},{"w":"placement","tr":"yerleştirme / işe yerleştirme","te":"Noun","tt":"Isim","de":"The act of finding a place for someone","dt":"Birisi için yer bulma eylemi","e1":"The university helps with job placement.","e1t":"Üniversite işe yerleştirme konusunda yardımcı oluyor.","e2":"A work placement (internship).","e2t":"Staj (iş yerleştirmesi)."},{"w":"planetary","tr":"gezegensel","te":"Adjective","tt":"Sıfat","de":"Relating to planets","dt":"Gezegenlerle ilgili","e1":"We are studying planetary motion.","e1t":"Gezegensel hareketi inceliyoruz.","e2":"Planetary systems.","e2t":"Gezegen sistemleri."},{"w":"plantation","tr":"plantasyon / dikim alanı","te":"Noun","tt":"Isim","de":"A large farm for growing crops like tea/coffee","dt":"Çay/kahve gibi mahsullerin yetiştirildiği büyük çiftlik","e1":"A tea plantation in Rize.","e1t":"Rize'de bir çay plantasyonu.","e2":"They worked on a cotton plantation.","e2t":"Pamuk tarlasında (plantasyonunda) çalıştılar."},{"w":"plaster","tr":"alçı / yara bandı / sıva","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance that becomes hard as it dries","dt":"Kurudukça sertleşen madde","e1":"He has his leg in plaster.","e1t":"Bacağı alçıda.","e2":"Apply a plaster to the cut.","e2t":"Kesiğe bir yara bandı yapıştır."},{"w":"plead","tr":"yalvarmak / savunma yapmak (mahkeme)","te":"Verb","tt":"Fiil","de":"To make an urgent emotional request","dt":"Acil duygusal bir talepte bulunmak","e1":"He pleaded with her to stay.","e1t":"Kalması için ona yalvardı.","e2":"How do you plead? (Guilty or not guilty).","e2t":"Savunmanız nedir? (Suçlu mu suçsuz mu?)"},{"w":"pledge","tr":"söz / vaat / rehin","te":"Noun/Verb","tt":"İsim/Fiil","de":"A serious promise","dt":"Ciddi bir söz","e1":"The government made a pledge to reduce taxes.","e1t":"Hükümet vergileri azaltma sözü (vaadi) verdi.","e2":"He pledged his support.","e2t":"Desteğini vaat etti."},{"w":"plot","tr":"olay örgüsü / arsa / komplo","te":"Noun/Verb","tt":"İsim/Fiil","de":"The story of a book/movie or a small piece of land","dt":"Kitap/film hikayesi veya küçük arazi parçası","e1":"The plot of the movie was very complicated.","e1t":"Filmin olay örgüsü çok karmaşıktı.","e2":"They bought a small plot of land to build a house.","e2t":"Ev inşa etmek için küçük bir arsa aldılar."},{"w":"plug","tr":"fiş / tıpa / takmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small plastic object with metal pins; to block","dt":"Metal pinleri olan küçük plastik nesne; tıkamak","e1":"Put the plug in the socket.","e1t":"Fişi prize tak.","e2":"Someone pulled the plug on the project.","e2t":"Birisi projenin fişini çekti (durdurdu)."},{"w":"plumber","tr":"tesisatçı","te":"Noun","tt":"Isim","de":"A person whose job is to repair water pipes","dt":"İşi su borularını tamir etmek olan kişi","e1":"We need to call a plumber to fix the leak.","e1t":"Sızıntıyı tamir etmek için bir tesisatçı çağırmamız gerekiyor.","e2":"He is a qualified plumber.","e2t":"O kalifiye bir tesisatçıdır."},{"w":"plunge","tr":"dalmak / hızla düşmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fall or move forward very quickly","dt":"Çok hızlı düşmek veya ileri hareket etmek","e1":"Prices plunged after the news.","e1t":"Haberlerden sonra fiyatlar hızla düştü.","e2":"He plunged into the cold water.","e2t":"Soğuk suya daldı."},{"w":"plural","tr":"çoğul","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to more than one","dt":"Birden fazla olanla ilgili","e1":"The plural of \"child\" is \"children\".","e1t":"\"Child\" kelimesinin çoğulu \"children\"dır.","e2":"A plural noun.","e2t":"Çoğul isim."},{"w":"point out","tr":"belirtmek / işaret etmek","te":"Verb","tt":"Fiil","de":"To tell someone a fact that they might not know","dt":"Birine bilmeyebileceği bir gerçeği söylemek","e1":"He pointed out that we were late.","e1t":"Geç kaldığımızı belirtti.","e2":"I should point out the risks involved.","e2t":"İçerilen riskleri belirtmeliyim."},{"w":"poison","tr":"zehir / zehirlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance that causes death or illness if swallowed","dt":"Yutulduğunda ölüme veya hastalığa neden olan madde","e1":"The arrow was covered in poison.","e1t":"Ok zehirle kaplıydı.","e2":"He was poisoned by bad food.","e2t":"Bozuk yemekten zehirlendi."},{"w":"poisonous","tr":"zehirli","te":"Adjective","tt":"Sıfat","de":"Containing poison","dt":"Zehir içeren","e1":"Some mushrooms are poisonous.","e1t":"Bazı mantarlar zehirlidir.","e2":"A poisonous snake.","e2t":"Zehirli bir yılan."},{"w":"poke","tr":"dürtmek / parmak atmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push something with your finger or a stick","dt":"Bir şeyi parmağınızla veya bir sopayla itmek","e1":"She poked him in the ribs to wake him up.","e1t":"Onu uyandırmak için kaburgalarına dürttü.","e2":"Stop poking me!","e2t":"Beni dürtmeyi bırak!"},{"w":"pole","tr":"direk / kutup","te":"Noun","tt":"İsim","de":"A long, thin stick of wood or metal; or a North/South point","dt":"Uzun, ince tahta veya metal sopa; veya Kuzey/Güney noktası","e1":"He climbed the flag pole.","e1t":"Bayrak direğine tırmandı.","e2":"The North Pole is extremely cold.","e2t":"Kuzey Kutbu aşırı derecede soğuktur."},{"w":"poll","tr":"anket / kamuoyu yoklaması","te":"Noun/Verb","tt":"İsim/Fiil","de":"A study in which people are asked for their opinions","dt":"İnsanlara fikirlerinin sorulduğu bir çalışma","e1":"The latest poll shows that the government is popular.","e1t":"Son anket hükümetin popüler olduğunu gösteriyor.","e2":"They polled 1,000 people.","e2t":"1.000 kişiyle anket (yoklama) yaptılar."},{"w":"popularity","tr":"popülerlik / yaygınlık","te":"Noun","tt":"İsim","de":"The state of being liked by many people","dt":"Birçok kişi tarafından sevilme durumu","e1":"The president's popularity is declining.","e1t":"Başkanın popülerliği düşüyor.","e2":"The popularity of online games is increasing.","e2t":"Çevrimiçi oyunların popülerliği artıyor."},{"w":"portion","tr":"porsiyon / kısım / hisse","te":"Noun/Verb","tt":"İsim/Fiil","de":"A part or share of something","dt":"Bir şeyin parçası veya hissesi","e1":"I only ate a small portion of the cake.","e1t":"Kekin sadece küçük bir porsiyonunu yedim.","e2":"A large portion of the budget goes to education.","e2t":"Bütçenin büyük bir kısmı eğitime gidiyor."},{"w":"pose","tr":"poz vermek / teşkil etmek / sormak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stay in a position for a photo or to cause a problem","dt":"Bir fotoğraf için bir konumda durmak veya bir soruna neden olmak","e1":"The pollution poses a threat to fish.","e1t":"Kirlilik balıklar için bir tehdit teşkil ediyor.","e2":"She posed for the camera.","e2t":"Kamera için poz verdi."},{"w":"position","tr":"konum / pozisyon / mevki","te":"Noun/Verb","tt":"İsim/Fiil","de":"The place where something or someone is","dt":"Bir şeyin veya birinin bulunduğu yer","e1":"What is your position on this issue?","e1t":"Bu konudaki pozisyonun (görüşün) nedir?","e2":"He has a high position in the company.","e2t":"Şirkette yüksek bir mevkisi var."},{"w":"possess","tr":"sahip olmak / zilyetliğinde bulundurmak","te":"Verb","tt":"Fiil","de":"To have or own something","dt":"Bir şeye sahip olmak","e1":"He possesses great talent.","e1t":"Büyük bir yeteneğe sahip.","e2":"It is illegal to possess these drugs.","e2t":"Bu ilaçlara sahip olmak (bulundurmak) yasa dışıdır."},{"w":"possession","tr":"mülk / sahiplik / zilyetlik","te":"Noun","tt":"İsim","de":"The fact that you own or have something","dt":"Bir şeye sahip olma veya bulundurma gerçeği","e1":"All his possessions were destroyed in the fire.","e1t":"Tüm eşyaları (mülkü) yangında yok oldu.","e2":"She is in possession of stolen goods.","e2t":"Çalıntı mallar onun zilyetliğinde (elinde)."},{"w":"postpone","tr":"ertelemek","te":"Verb","tt":"Fiil","de":"To delay an event until a later time","dt":"Bir olayı daha sonraki bir zamana ertelemek","e1":"The meeting has been postponed until next week.","e1t":"Toplantı gelecek haftaya ertelendi.","e2":"Don't postpone what you can do today.","e2t":"Bugün yapabileceğini erteleme."},{"w":"potentially","tr":"potansiyel olarak","te":"Adverb","tt":"Zarf","de":"Possibly","dt":"Muhtemelen","e1":"This is a potentially dangerous situation.","e1t":"Bu, potansiyel olarak tehlikeli bir durumdur.","e2":"The new technology is potentially very useful.","e2t":"Yeni teknoloji potansiyel olarak çok yararlı."},{"w":"pottery","tr":"çömlekçilik / çanak çömlek","te":"Noun","tt":"İsim","de":"Plates, bowls, etc. made from baked clay","dt":"Pişmiş kilden yapılan tabaklar, kaseler vb.","e1":"He is taking a pottery class.","e1t":"Çömlekçilik sınıfına gidiyor.","e2":"Ancient Greek pottery is famous.","e2t":"Antik Yunan çanak çömlekleri ünlüdür."},{"w":"powerless","tr":"güçsüz / çaresiz","te":"Adjective","tt":"Sıfat","de":"Having no power","dt":"Gücü olmayan","e1":"He felt powerless to change the situation.","e1t":"Durumu değiştirmek için kendini çaresiz (güçsüz) hissetti.","e2":"A powerless government.","e2t":"Güçsüz bir hükümet."},{"w":"practically","tr":"neredeyse / pratik olarak","te":"Adverb","tt":"Zarf","de":"Almost or in a practical way","dt":"Neredeyse veya pratik bir şekilde","e1":"The work is practically finished.","e1t":"İş neredeyse bitti.","e2":"Practically speaking, we can't afford it.","e2t":"Pratik olarak konuşursak, buna gücümüz yetmez."},{"w":"practitioner","tr":"uygulayıcı / pratisyen","te":"Noun","tt":"İsim","de":"Someone who works in a particular profession","dt":"Belirli bir meslekte çalışan kişi","e1":"He is a general practitioner (GP).","e1t":"O bir pratisyen hekimdir.","e2":"A legal practitioner.","e2t":"Bir hukuk uygulayıcısı (avukat/hukukçu)."},{"w":"preach","tr":"vaaz vermek / öğütlemek","te":"Verb","tt":"Fiil","de":"To give a religious talk or to give strong advice","dt":"Dini konuşma yapmak veya güçlü tavsiyeler vermek","e1":"The priest preached about forgiveness.","e1t":"Rahip bağışlama üzerine vaaz verdi.","e2":"Stop preaching at me!","e2t":"Bana öğüt vermeyi bırak!"},{"w":"precaution","tr":"önlem / tedbir","te":"Noun","tt":"İsim","de":"Something done to prevent something bad","dt":"Kötü bir şeyi önlemek için yapılan şey","e1":"You should take precautions against the flu.","e1t":"Gribe karşı önlem (tedbir) almalısın.","e2":"As a precaution, we checked the brakes.","e2t":"Tedbir olarak frenleri kontrol ettik."},{"w":"precede","tr":"","te":"den önce gelmek","tt":"Verb","de":"Fiil","dt":"To happen or exist before something else","e1":"Başka bir şeyden önce gerçekleşmek veya var olmak","e1t":"The dark clouds preceded the storm.","e2":"Kara bulutlar fırtınadan önce geldi.","e2t":"A short intro preceded the performance."},{"w":"precious","tr":"değerli / kıymetli","te":"Adjective","tt":"Sıfat","de":"Very valuable","dt":"Çok değerli","e1":"Gold is a precious metal.","e1t":"Altın değerli bir metaldir.","e2":"My time is precious.","e2t":"Zamanım kıymetlidir."},{"w":"precise","tr":"kesin / tam / titiz","te":"Adjective","tt":"Sıfat","de":"Exact and accurate","dt":"Tam ve doğru","e1":"Can you give me the precise measurements?","e1t":"Bana kesin ölçüleri verebilir misin?","e2":"He is very precise in his work.","e2t":"İşinde çok titizdir."},{"w":"precision","tr":"hassasiyet / kesinlik","te":"Noun","tt":"İsim","de":"The quality of being exact","dt":"Tam olma özelliği","e1":"The work was done with great precision.","e1t":"İş büyük bir hassasiyetle yapıldı.","e2":"Precision tools.","e2t":"Hassas (kesinlik gerektiren) araçlar."},{"w":"predictable","tr":"öngörülebilir / tahmin edilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be known before it happens","dt":"Olmadan önce bilinebilen","e1":"The movie had a very predictable ending.","e1t":"Filmin çok tahmin edilebilir bir sonu vardı.","e2":"Predictable results.","e2t":"Öngörülebilir sonuçlar."},{"w":"prediction","tr":"tahmin / öngörü","te":"Noun","tt":"İsim","de":"A statement about what will happen in the future","dt":"Gelecekte ne olacağına dair ifade","e1":"It is difficult to make a prediction about the weather.","e1t":"Hava durumu hakkında tahmin yapmak zordur.","e2":"My prediction came true.","e2t":"Tahminim doğru çıktı."},{"w":"predominant","tr":"baskın / hakim","te":"Adjective","tt":"Sıfat","de":"More noticeable or important than others","dt":"Diğerlerinden daha fark edilebilir veya önemli","e1":"English is the predominant language in international business.","e1t":"Uluslararası iş dünyasında İngilizce hakim (baskın) dildir.","e2":"The predominant color in the room is blue.","e2t":"Odadaki baskın renk mavidir."},{"w":"prejudice","tr":"önyargı","te":"Noun/Verb","tt":"İsim/Fiil","de":"An unfair opinion formed without enough knowledge","dt":"Yeterli bilgi olmadan oluşan adaletsiz görüş","e1":"We must fight against racial prejudice.","e1t":"Irksal önyargıya karşı savaşmalıyız.","e2":"He is prejudiced against foreigners.","e2t":"Yabancılara karşı önyargılıdır."},{"w":"preliminary","tr":"ön / başlangıç","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Coming before a more important action or event","dt":"Daha önemli bir eylem veya olaydan önce gelen","e1":"The preliminary results are positive.","e1t":"Ön (ilk) sonuçlar olumlu.","e2":"After a few preliminary remarks, the meeting began.","e2t":"Birkaç ön açıklamadan sonra toplantı başladı."},{"w":"prescribe","tr":"reçete yazmak / emretmek","te":"Verb","tt":"Fiil","de":"To tell someone what medicine to take","dt":"Birine hangi ilacı alacağını söylemek","e1":"The doctor prescribed antibiotics.","e1t":"Doktor antibiyotik yazdı.","e2":"The law prescribes a heavy penalty.","e2t":"Kanun ağır bir ceza öngörüyor (emrediyor)."},{"w":"prescription","tr":"reçete","te":"Noun","tt":"İsim","de":"A piece of paper on which a doctor writes medicine","dt":"Doktorun üzerine ilaç yazdığı kağıt parçası","e1":"I need to take this prescription to the pharmacy.","e1t":"Bu reçeteyi eczaneye götürmem gerekiyor.","e2":"Prescription drugs.","e2t":"Reçeteli ilaçlar."},{"w":"preservation","tr":"koruma / muhafaza","te":"Noun","tt":"İsim","de":"The act of preserving something","dt":"Bir şeyi koruma eylemi","e1":"The preservation of the environment.","e1t":"Çevrenin korunması.","e2":"Food preservation.","e2t":"Gıdaların muhafazası."},{"w":"preserve","tr":"korumak / muhafaza etmek / reçel","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep something as it is, especially to stop it being damaged","dt":"Bir şeyi olduğu gibi tutmak, özellikle zarar görmesini engellemek","e1":"We must preserve historical buildings.","e1t":"Tarihi binaları korumalıyız.","e2":"Salt is used to preserve meat.","e2t":"Tuz, eti muhafaza etmek (saklamak) için kullanılır."},{"w":"presidency","tr":"başkanlık","te":"Noun","tt":"İsim","de":"The job or time of being a president","dt":"Başkan olma işi veya süresi","e1":"He is running for the presidency.","e1t":"Başkanlık için yarışıyor.","e2":"During his presidency, the economy grew.","e2t":"Onun başkanlığı sırasında ekonomi büyüdü."},{"w":"prestigious","tr":"saygın / prestijli","te":"Adjective","tt":"Sıfat","de":"Very much respected and admired","dt":"Çok saygı ve hayranlık duyulan","e1":"He won a prestigious literary award.","e1t":"Prestijli bir edebiyat ödülü kazandı.","e2":"A prestigious job in a law firm.","e2t":"Bir hukuk bürosunda prestijli bir iş."},{"w":"presumably","tr":"muhtemelen / herhalde","te":"Adverb","tt":"Zarf","de":"Used to say what you think is likely to happen","dt":"Muhtemelen ne olacağını düşündüğünüzü söylemek için kullanılır","e1":"Presumably, he'll be late as usual.","e1t":"Muhtemelen her zamanki gibi geç kalacaktır.","e2":"She's not here, so presumably she's at home.","e2t":"Burada değil, o halde muhtemelen evdedir."},{"w":"prevalence","tr":"yaygınlık","te":"Noun","tt":"İsim","de":"The fact that something is very common","dt":"Bir şeyin çok yaygın olması gerçeği","e1":"The prevalence of smoking among teenagers.","e1t":"Gençler arasında sigara içme yaygınlığı.","e2":"We are concerned about the prevalence of the disease.","e2t":"Hastalığın yaygınlığı konusunda endişeliyiz."},{"w":"preventive","tr":"önleyici / koruyucu","te":"Adjective","tt":"Sıfat","de":"Intended to stop something from happening","dt":"Bir şeyin olmasını durdurmayı amaçlayan","e1":"Preventive medicine focuses on healthy living.","e1t":"Koruyucu tıp sağlıklı yaşama odaklanır.","e2":"We took preventive measures against fire.","e2t":"Yangına karşı önleyici tedbirler aldık."},{"w":"previous","tr":"önceki / geçmiş","te":"Adjective","tt":"Sıfat","de":"Happening or existing before something else","dt":"Başka bir şeyden önce gerçekleşen veya var olan","e1":"I have no previous experience in this field.","e1t":"Bu alanda daha önce (geçmiş) bir deneyimim yok.","e2":"The previous owner of the house.","e2t":"Evin önceki sahibi."},{"w":"previously","tr":"önceden / eskiden","te":"Adverb","tt":"Zarf","de":"Before the present time or the time mentioned","dt":"Şu andan veya bahsedilen zamandan önce","e1":"He had previously worked as a teacher.","e1t":"Daha önce (eskiden) öğretmen olarak çalışmıştı.","e2":"As I mentioned previously...","e2t":"Daha önce belirttiğim gibi..."},{"w":"prey","tr":"av / kurban","te":"Noun/Verb","tt":"İsim/Fiil","de":"An animal that is hunted and eaten by another","dt":"Başka bir hayvan tarafından avlanan ve yenen hayvan","e1":"The eagle is a bird of prey.","e1t":"Kartal bir yırtıcı (avcı) kuştur.","e2":"Deer are easy prey for lions.","e2t":"Geyikler aslanlar için kolay avdır."},{"w":"prime","tr":"ana / başlıca / en verimli dönem","te":"Adjective/Noun/Verb","tt":"Most important or in the best condition","de":"En önemli veya en iyi durumda","dt":"He is in the prime of his life.","e1":"Hayatının en verimli döneminde.","e1t":"The prime suspect in the murder case.","e2":"Cinayet davasındaki başlıca (baş) şüpheli.","e2t":""},{"w":"primitive","tr":"ilkel","te":"Adjective","tt":"Sıfat","de":"Relating to human society at a very early stage","dt":"Çok erken bir aşamadaki insan toplumuyla ilgili","e1":"Primitive humans lived in caves.","e1t":"İlkel insanlar mağaralarda yaşarlardı.","e2":"The tools they used were very primitive.","e2t":"Kullandıkları aletler çok ilkeldi."},{"w":"prior","tr":"öncelikli / önceki","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Existing or happening before something else","dt":"Başka bir şeyden önce var olan veya gerçekleşen","e1":"I have a prior engagement.","e1t":"Önceden verilmiş bir sözüm (randevum) var.","e2":"Prior to the meeting, we had a coffee.","e2t":"Toplantıdan önce bir kahve içtik."},{"w":"privacy","tr":"gizlilik / mahremiyet","te":"Noun","tt":"İsim","de":"The state of being free from public attention","dt":"Kamuoyunun dikkatinden uzak olma durumu","e1":"I value my privacy.","e1t":"Mahremiyetime değer veririm.","e2":"Invasion of privacy.","e2t":"Özel hayatın (gizliliğin) ihlali."},{"w":"privilege","tr":"ayrıcalık / imtiyaz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A special advantage that only one person or group has","dt":"Sadece bir kişi veya grubun sahip olduğu özel avantaj","e1":"It was a privilege to meet the president.","e1t":"Başkanla tanışmak bir ayrıcalıktı.","e2":"Education should be a right, not a privilege.","e2t":"Eğitim bir imtiyaz değil, hak olmalıdır."},{"w":"privileged","tr":"ayrıcalıklı","te":"Adjective","tt":"Sıfat","de":"Having a special advantage","dt":"Özel bir avantaja sahip olan","e1":"He comes from a privileged background.","e1t":"Ayrıcalıklı bir aileden/geçmişten geliyor.","e2":"Privileged information.","e2t":"Gizli (ayrıcalıklı) bilgi."},{"w":"probability","tr":"olasılık / ihtimal","te":"Noun","tt":"İsim","de":"The level of possibility of something happening","dt":"Bir şeyin gerçekleşme olasılık düzeyi","e1":"There is a high probability of rain today.","e1t":"Bugün yüksek bir yağmur ihtimali var.","e2":"What is the probability of success?","e2t":"Başarı olasılığı nedir?"},{"w":"probable","tr":"muhtemel / olası","te":"Adjective","tt":"Sıfat","de":"Likely to be true or to happen","dt":"Doğru olması veya gerçekleşmesi muhtemel","e1":"It is probable that they will win.","e1t":"Kazanmaları muhtemeldir.","e2":"The probable cause of the fire.","e2t":"Yangının muhtemel nedeni."},{"w":"probe","tr":"araştırmak / soruşturma / sonda","te":"Verb/Noun","tt":"Fiil/İsim","de":"To examine something carefully","dt":"Bir şeyi dikkatlice incelemek","e1":"The police are probing the company's finances.","e1t":"Polis şirketin finansmanını araştırıyor.","e2":"A space probe.","e2t":"Uzay sondası."},{"w":"procedure","tr":"prosedür / işlem / yöntem","te":"Noun","tt":"İsim","de":"A set of actions that is the official way of doing something","dt":"Bir şeyi yapmanın resmi yolu olan eylemler bütünü","e1":"What is the procedure for applying for a visa?","e1t":"Vize başvurusu için prosedür nedir?","e2":"Follow the safety procedures.","e2t":"Güvenlik prosedürlerini takip edin."},{"w":"proceed","tr":"ilerlemek / devam etmek","te":"Verb","tt":"Fiil","de":"To continue as planned","dt":"Planlandığı gibi devam etmek","e1":"Please proceed to the gate.","e1t":"Lütfen kapıya (perona) doğru ilerleyin.","e2":"We will proceed with the investigation.","e2t":"Soruşturmaya devam edeceğiz."},{"w":"proceedings","tr":"yasal işlem / tutanak / faaliyetler","te":"Noun","tt":"İsim","de":"Legal action or a formal series of events","dt":"Yasal işlem veya resmi olaylar dizisi","e1":"The legal proceedings against the company have started.","e1t":"Şirkete karşı yasal işlemler başladı.","e2":"I read the proceedings of the conference.","e2t":"Konferans tutanaklarını okudum."},{"w":"proclaim","tr":"ilan etmek / duyurmak","te":"Verb","tt":"Fiil","de":"To announce something publicly or officially","dt":"Bir şeyi kamuoyuna veya resmi olarak duyurmak","e1":"They proclaimed independence.","e1t":"Bağımsızlık ilan ettiler.","e2":"He proclaimed himself king.","e2t":"Kendini kral ilan etti."},{"w":"productive","tr":"verimli / üretken","te":"Adjective","tt":"Sıfat","de":"Producing a lot of goods or results","dt":"Çok fazla mal veya sonuç üreten","e1":"It was a very productive meeting.","e1t":"Çok verimli bir toplantıydı.","e2":"We need to be more productive at work.","e2t":"İş yerinde daha üretken olmalıyız."},{"w":"productivity","tr":"verimlilik / üretkenlik","te":"Noun","tt":"İsim","de":"The rate at which goods are produced","dt":"Malların üretilme hızı","e1":"The new technology increased productivity.","e1t":"Yeni teknoloji verimliliği artırdı.","e2":"We are monitoring staff productivity.","e2t":"Personel verimliliğini izliyoruz."},{"w":"professional","tr":"profesyonel / mesleki","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a job or doing something as a job","dt":"Bir işle ilgili olan veya bir şeyi iş olarak yapan","e1":"He is a professional football player.","e1t":"O profesyonel bir futbolcudur.","e2":"Use a professional approach.","e2t":"Profesyonel bir yaklaşım kullanın."},{"w":"proficiency","tr":"yeterlilik / ustalık","te":"Noun","tt":"İsim","de":"Skill and knowledge in a particular subject","dt":"Belirli bir konuda beceri ve bilgi","e1":"You need to prove your English proficiency.","e1t":"İngilizce yeterliliğinizi kanıtlamanız gerekiyor.","e2":"He has a high level of proficiency in coding.","e2t":"Kodlama konusunda yüksek düzeyde ustalığa sahip."},{"w":"proficient","tr":"yetkin / usta / becerikli","te":"Adjective","tt":"Sıfat","de":"Skilled and experienced","dt":"Becerikli ve deneyimli","e1":"She is proficient in three languages.","e1t":"Üç dilde yetkindir (ustadır).","e2":"He is a proficient driver.","e2t":"O becerikli bir sürücüdür."},{"w":"profile","tr":"profil / yan görünüş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A description of someone or a side view of a face","dt":"Birinin açıklaması veya yüzün yan görünüşü","e1":"I saw his profile in the newspaper.","e1t":"Gazetede onun profilini (tanıtımını) gördüm.","e2":"You can update your social media profile.","e2t":"Sosyal medya profilini güncelleyebilirsin."},{"w":"profitable","tr":"kârlı / yararlı","te":"Adjective","tt":"Sıfat","de":"Resulting in a profit or benefit","dt":"Kâr veya yararla sonuçlanan","e1":"This is a very profitable business.","e1t":"Bu çok kârlı bir iştir.","e2":"We had a profitable discussion.","e2t":"Yararlı bir tartışma yaptık."},{"w":"profound","tr":"derin / köklü","te":"Adjective","tt":"Sıfat","de":"Very great or showing great knowledge","dt":"Çok büyük veya derin bilgi gösteren","e1":"His words had a profound effect on me.","e1t":"Sözlerinin üzerimde derin bir etkisi oldu.","e2":"A profound discovery.","e2t":"Köklü (derin) bir keşif."},{"w":"program / programme","tr":"program / programlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A set of instructions or a series of events","dt":"Talimatlar bütünü veya olaylar dizisi","e1":"What is your favorite TV program?","e1t":"En sevdiğin TV programı hangisi?","e2":"I am learning how to program in Python.","e2t":"Python'da nasıl programlama yapılacağını öğreniyorum."},{"w":"progressive","tr":"ilerici / kademeli","te":"Adjective","tt":"Sıfat","de":"Using new ideas or happening gradually","dt":"Yeni fikirler kullanan veya kademeli gerçekleşen","e1":"He has progressive political views.","e1t":"İlerici siyasi görüşleri var.","e2":"The disease is progressive.","e2t":"Hastalık ilerleyicidir (kademeli olarak artar)."},{"w":"prohibit","tr":"yasaklamak / engellemek","te":"Verb","tt":"Fiil","de":"To officially refuse to allow something","dt":"Bir şeye resmi olarak izin vermeyi reddetmek","e1":"Smoking is prohibited in this area.","e1t":"Bu alanda sigara içmek yasaktır.","e2":"The law prohibits the sale of alcohol to minors.","e2t":"Kanun küçüklere alkol satışını yasaklar."},{"w":"prohibition","tr":"yasak / yasaklama","te":"Noun","tt":"İsim","de":"The act of officially forbidding something","dt":"Bir şeyi resmi olarak yasaklama eylemi","e1":"The prohibition of alcohol in the 1920s.","e1t":"1920'lerdeki alkol yasağı.","e2":"There is a strict prohibition against smoking here.","e2t":"Burada sigara içilmesine karşı kesin bir yasak var."},{"w":"projector","tr":"projektör / yansıtıcı","te":"Noun","tt":"İsim","de":"A device that throws an image onto a screen","dt":"Görüntüyü ekrana yansıtan cihaz","e1":"We need a projector for the presentation.","e1t":"Sunum için bir projektöre ihtiyacımız var.","e2":"The classroom is equipped with a digital projector.","e2t":"Sınıf bir dijital projektörle donatılmış."},{"w":"prompt","tr":"çabuk / anında / teşvik etmek / komut","te":"Adjective/Verb/Noun","tt":"Done without delay; to make someone do something","de":"Gecikmeden yapılan; birine bir şey yaptırmak","dt":"Thank you for your prompt reply.","e1":"Hızlı (anında) cevabınız için teşekkürler.","e1t":"I am writing a prompt for the AI.","e2":"Yapay zeka için bir komut (prompt) yazıyorum.","e2t":""},{"w":"pronunciation","tr":"telaffuz","te":"Noun","tt":"İsim","de":"The way in which a word is pronounced","dt":"Bir kelimenin telaffuz edilme biçimi","e1":"Your pronunciation is very clear.","e1t":"Telaffuzun çok net.","e2":"I need to practice my English pronunciation.","e2t":"İngilizce telaffuzum üzerine çalışmam gerekiyor."},{"w":"propeller","tr":"pervane","te":"Noun","tt":"İsim","de":"A device with blades that turn fast to move a ship/plane","dt":"Gemi/uçağı hareket ettirmek için hızlı dönen kanatlı cihaz","e1":"The airplane's propeller began to spin.","e1t":"Uçağın pervanesi dönmeye başladı.","e2":"A ship's propeller.","e2t":"Gemi pervanesi."},{"w":"proper","tr":"uygun / doğru / düzgün","te":"Adjective","tt":"Sıfat","de":"Right or suitable; correct","dt":"Doğru veya uygun; düzgün","e1":"Please follow the proper procedure.","e1t":"Lütfen uygun (doğru) prosedürü takip edin.","e2":"He hasn't had a proper meal all day.","e2t":"Tüm gün düzgün bir yemek yemedi."},{"w":"properly","tr":"düzgünce / hakkıyla","te":"Adverb","tt":"Zarf","de":"In the right way","dt":"Doğru şekilde","e1":"Is the machine working properly?","e1t":"Makine düzgün çalışıyor mu?","e2":"You must do it properly.","e2t":"Onu hakkıyla (düzgünce) yapmalısın."},{"w":"proportion","tr":"oran / porsiyon","te":"Noun","tt":"İsim","de":"The number or amount of a group compared to the whole","dt":"Bir grubun bütüne kıyasla sayısı veya miktarı","e1":"A large proportion of the students are from Turkey.","e1t":"Öğrencilerin büyük bir oranı Türkiye'dendir.","e2":"The proportions of the building are perfect.","e2t":"Binanın oranları mükemmel."},{"w":"propose","tr":"önermek / teklif etmek","te":"Verb","tt":"Fiil","de":"To suggest a plan or action","dt":"Bir plan veya eylem önermek","e1":"I propose that we wait until tomorrow.","e1t":"Yarına kadar beklememizi öneriyorum.","e2":"He proposed to his girlfriend yesterday.","e2t":"Dün kız arkadaşına evlilik teklif etti."},{"w":"prosperous","tr":"müreffeh / zengin / başarılı","te":"Adjective","tt":"Sıfat","de":"Successful and rich","dt":"Başarılı ve zengin","e1":"A prosperous businessman.","e1t":"Başarılı (zengin) bir iş adamı.","e2":"A prosperous country.","e2t":"Müreffeh bir ülke."},{"w":"protective","tr":"koruyucu","te":"Adjective","tt":"Sıfat","de":"Intended to protect someone or something","dt":"Birini veya bir şeyi korumayı amaçlayan","e1":"Protective clothing.","e1t":"Koruyucu kıyafet.","e2":"He is very protective of his younger sister.","e2t":"Küçük kız kardeşine karşı çok korumacıdır."},{"w":"protein","tr":"protein","te":"Noun","tt":"İsim","de":"A substance found in food like meat, eggs, and beans","dt":"Et, yumurta ve fasulye gibi yiyeceklerde bulunan madde","e1":"Eggs are a good source of protein.","e1t":"Yumurta iyi bir protein kaynağıdır.","e2":"Muscle building requires protein.","e2t":"Kas yapımı protein gerektirir."},{"w":"protest","tr":"protesto etmek / itiraz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To show disagreement publicly","dt":"Anlaşmazlığı kamuoyuna göstermek","e1":"They are protesting against the new law.","e1t":"Yeni yasaya karşı protesto yapıyorlar.","e2":"A peaceful protest.","e2t":"Barışçıl bir protesto."},{"w":"province","tr":"vilayet / il / eyalet","te":"Noun","tt":"İsim","de":"A large section of a country","dt":"Bir ülkenin büyük bir bölümü","e1":"Trabzon is a province of Turkey.","e1t":"Trabzon Türkiye'nin bir ilidir.","e2":"The eastern provinces.","e2t":"Doğu illeri."},{"w":"provision","tr":"hüküm / tedarik / koşul","te":"Noun/Verb","tt":"İsim/Fiil","de":"The act of providing or a rule in a legal document","dt":"Sağlama eylemi veya yasal belgedeki kural","e1":"The government made provision for the refugees.","e1t":"Hükümet mülteciler için tedarik (hazırlık) yaptı.","e2":"A provision in the contract.","e2t":"Sözleşmedeki bir hüküm (madde)."},{"w":"psychological","tr":"psikolojik","te":"Adjective","tt":"Sıfat","de":"Relating to the mind and behavior","dt":"Zihin ve davranışla ilgili","e1":"He is suffering from psychological problems.","e1t":"Psikolojik sorunlardan muzdarip.","e2":"The psychological effects of war.","e2t":"Savaşın psikolojik etkileri."},{"w":"psychologist","tr":"psikolog","te":"Noun","tt":"İsim","de":"A person who studies the mind and behavior","dt":"Zihin ve davranışı inceleyen kişi","e1":"She went to see a psychologist.","e1t":"Bir psikoloğa görünmeye gitti.","e2":"Educational psychologist.","e2t":"Eğitim psikoloğu."},{"w":"psychology","tr":"psikoloji","te":"Noun","tt":"İsim","de":"The scientific study of the mind and behavior","dt":"Zihin ve davranışın bilimsel incelenmesi","e1":"He is studying child psychology.","e1t":"Çocuk psikolojisi okuyor.","e2":"The psychology of marketing.","e2t":"Pazarlama psikolojisi."},{"w":"publicity","tr":"tanıtım / ilan / reklam","te":"Noun","tt":"İsim","de":"Information that attracts the public's attention","dt":"Halkın dikkatini çeken bilgi","e1":"The event received a lot of publicity.","e1t":"Etkinlik çok fazla ilgi (tanıtım) gördü.","e2":"Bad publicity.","e2t":"Kötü reklam (imaj)."},{"w":"publisher","tr":"yayıncı / yayınevi","te":"Noun","tt":"İsim","de":"A person or company that publishes books","dt":"Kitap yayımlayan kişi veya şirket","e1":"He sent his manuscript to several publishers.","e1t":"El yazmasını birkaç yayınevine gönderdi.","e2":"The publisher announced a new series of textbooks.","e2t":"Yayıncı yeni bir ders kitabı serisi duyurdu."},{"w":"pull up","tr":"yukarı çekmek / durmak (araç)","te":"Verb","tt":"Fiil","de":"To move upwards or to stop a vehicle","dt":"Yukarı hareket ettirmek veya bir aracı durdurmak","e1":"The car pulled up in front of the house.","e1t":"Araba evin önünde durdu.","e2":"Pull up a chair and join us.","e2t":"Bir sandalye çek ve bize katıl."},{"w":"pulse","tr":"nabız / vuruş","te":"Noun/Verb","tt":"İsim/Fiil","de":"The regular beat of blood through the body","dt":"Kanın vücuttaki düzenli vuruşu","e1":"The doctor checked his pulse.","e1t":"Doktor onun nabzını kontrol etti.","e2":"The pulse of the city.","e2t":"Şehrin nabzı (ritmi)."},{"w":"pump","tr":"pompa / pompalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A machine that moves liquid or gas","dt":"Sıvı veya gazı hareket ettiren makine","e1":"I need a pump for my bicycle tires.","e1t":"Bisiklet lastiklerim için bir pompaya ihtiyacım var.","e2":"The heart pumps blood around the body.","e2t":"Kalp vücuda kan pompalar."},{"w":"punch","tr":"yumruklamak / delgeç","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit with a fist or a tool for making holes","dt":"Yumrukla vurmak veya delik açma aleti","e1":"He punched the wall in anger.","e1t":"Öfkeyle duvarı yumrukladı.","e2":"I need a paper punch for these documents.","e2t":"Bu belgeler için bir delgece ihtiyacım var."},{"w":"punctuality","tr":"dakiklik","te":"Noun","tt":"İsim","de":"The habit of being on time","dt":"Zamanında olma alışkanlığı","e1":"Punctuality is important in professional life.","e1t":"Profesyonel hayatta dakiklik önemlidir.","e2":"I value punctuality in my students.","e2t":"Öğrencilerimde dakikliğe değer veririm."},{"w":"punctuation","tr":"noktalama","te":"Noun","tt":"İsim","de":"The marks used in writing (e.g., periods, commas)","dt":"Yazıda kullanılan işaretler (nokta, virgül vb.)","e1":"You need to improve your punctuation.","e1t":"Noktalamanı geliştirmen gerekiyor.","e2":"Punctuation marks.","e2t":"Noktalama işaretleri."},{"w":"punish","tr":"cezalandırmak","te":"Verb","tt":"Fiil","de":"To make someone suffer for a crime or mistake","dt":"Bir suçu veya hatası için birine acı çektirmek","e1":"They were punished for their actions.","e1t":"Eylemleri için cezalandırıldılar.","e2":"The law punishes drunk driving.","e2t":"Kanun alkollü araç kullanmayı cezalandırır."},{"w":"punishment","tr":"ceza","te":"Noun","tt":"İsim","de":"The act of punishing or the penalty given","dt":"Cezalandırma eylemi veya verilen ceza","e1":"Capital punishment (death penalty).","e1t":"İdam cezası.","e2":"He received a light punishment.","e2t":"Hafif bir ceza aldı."},{"w":"purchase","tr":"satın almak / alım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To buy something","dt":"Bir şey satın almak","e1":"I purchased a new laptop yesterday.","e1t":"Dün yeni bir dizüstü bilgisayar satın aldım.","e2":"The purchase of the house was a big decision.","e2t":"Evi satın alma (alımı) büyük bir karardı."},{"w":"pure","tr":"saf / temiz / katıksız","te":"Adjective","tt":"Sıfat","de":"Not mixed with anything else; clean","dt":"Başka bir şeyle karışmamış; temiz","e1":"This ring is made of pure gold.","e1t":"Bu yüzük saf altından yapılmıştır.","e2":"Pure water.","e2t":"Saf su."},{"w":"purely","tr":"tamamen / sadece","te":"Adverb","tt":"Zarf","de":"Completely or only","dt":"Sırf veya sadece","e1":"It was purely by chance.","e1t":"Tamamen tesadüf eseriydi.","e2":"The decision was based purely on merit.","e2t":"Karar tamamen (sadece) liyakate dayalıydı."},{"w":"purification","tr":"arıtma / temizleme","te":"Noun","tt":"İsim","de":"The act of making something pure","dt":"Bir şeyi saf hale getirme eylemi","e1":"Water purification system.","e1t":"Su arıtma sistemi.","e2":"Air purification.","e2t":"Hava temizleme (arıtma)."},{"w":"purity","tr":"saflık / temizlik","te":"Noun","tt":"İsim","de":"The state of being pure","dt":"Saf olma durumu","e1":"The purity of the water.","e1t":"Suyun saflığı (temizliği).","e2":"Moral purity.","e2t":"Ahlaki saflık."},{"w":"pursue","tr":"sürdürmek / kovalamak / takip etmek","te":"Verb","tt":"Fiil","de":"To follow or to try to achieve something","dt":"Takip etmek veya bir şeyi başarmaya çalışmak","e1":"He decided to pursue a career in medicine.","e1t":"Tıp alanında kariyer yapmaya (sürdürmeye) karar verdi.","e2":"The police pursued the suspect.","e2t":"Polis şüpheliyi kovaladı."},{"w":"pursuit","tr":"takip / uğraş / kovalama","te":"Noun","tt":"İsim","de":"The act of pursuing or a hobby/activity","dt":"Takip etme eylemi veya hobi/faaliyet","e1":"The pursuit of happiness.","e1t":"Mutluluk arayışı (peşinde koşma).","e2":"Outdoor pursuits (hobbies).","e2t":"Doğa sporları (uğraşları)."},{"w":"pushy","tr":"ısrarcı / kaba / girişken","te":"Adjective","tt":"Sıfat","de":"Trying too hard to get what you want","dt":"İstediğini elde etmek için çok fazla uğraşan (rahatsız edici boyutta)","e1":"I don't like pushy salesmen.","e1t":"Israrcı (sıkboğaz eden) satıcıları sevmem.","e2":"You need to be more pushy if you want that job.","e2t":"O işi istiyorsan biraz daha girişken olmalısın."},{"w":"puzzle","tr":"bulmaca / bilmece / şaşırtmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A game or a difficult question; to confuse","dt":"Oyun veya zor soru; şaşırtmak","e1":"I enjoy doing crossword puzzles.","e1t":"Kare bulmaca çözmekten zevk alırım.","e2":"His reaction puzzled me.","e2t":"Onun tepkisi beni şaşırttı."},{"w":"qualified","tr":"nitelikli / kalifiye / yetkili","te":"Adjective","tt":"Sıfat","de":"Having the necessary skills or documents","dt":"Gerekli becerilere veya belgelere sahip olan","e1":"She is a highly qualified teacher.","e1t":"O çok nitelikli (kalifiye) bir öğretmendir.","e2":"He is qualified to practice law.","e2t":"Avukatlık yapmaya yetkilidir."},{"w":"qualify","tr":"hak kazanmak / nitelendirmek","te":"Verb","tt":"Fiil","de":"To succeed in reaching a stage; to have the skills","dt":"Bir aşamaya ulaşmada başarılı olmak; becerilere sahip olmak","e1":"Turkey qualified for the World Cup.","e1t":"Türkiye Dünya Kupası'na katılmaya hak kazandı.","e2":"This experience qualifies you for the job.","e2t":"Bu deneyim seni iş için uygun kılar."},{"w":"qualitative","tr":"nitel / niteliksel","te":"Adjective","tt":"Sıfat","de":"Relating to how good something is, not its size","dt":"Bir şeyin ne kadar iyi olduğuyla ilgili, boyutuyla değil","e1":"We need to do a qualitative analysis of the data.","e1t":"Verilerin nitel (kaliteye dayalı) bir analizini yapmalıyız.","e2":"Qualitative research.","e2t":"Nitel araştırma."},{"w":"quantitative","tr":"nicel / sayısal","te":"Adjective","tt":"Sıfat","de":"Relating to amounts or numbers","dt":"Miktarlar veya sayılarla ilgili","e1":"Quantitative data (numbers, statistics).","e1t":"Nicel veriler (sayılar, istatistikler).","e2":"We need quantitative evidence.","e2t":"Sayısal (nicel) kanıta ihtiyacımız var."},{"w":"quarrel","tr":"tartışmak / kavga","te":"Verb/Noun","tt":"Fiil/İsim","de":"An angry disagreement","dt":"Öfkeli bir anlaşmazlık","e1":"They often quarrel about money.","e1t":"Sık sık para hakkında tartışırlar.","e2":"I have no quarrel with you.","e2t":"Seninle bir alıp veremediğim (kavgam) yok."},{"w":"quarterly","tr":"üç ayda bir","te":"Adjective/Adverb/Noun","tt":"Happening every three months","de":"Her üç ayda bir gerçekleşen","dt":"The company publishes a quarterly report.","e1":"Şirket üç ayda bir rapor yayımlıyor.","e1t":"We pay the bills quarterly.","e2":"Faturaları üç ayda bir öderiz.","e2t":""},{"w":"quest","tr":"arayış / keşif","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long search for something","dt":"Bir şey için yapılan uzun arama","e1":"His quest for knowledge.","e1t":"Onun bilgi arayışı.","e2":"They are on a quest to find the truth.","e2t":"Gerçeği bulma arayışındalar."},{"w":"questionable","tr":"şüpheli / tartışmalı","te":"Adjective","tt":"Sıfat","de":"Not certain or not honest","dt":"Kesin olmayan veya dürüst olmayan","e1":"The results are questionable.","e1t":"Sonuçlar tartışmalıdır (şüphelidir).","e2":"His business methods are questionable.","e2t":"İş yöntemleri şüphelidir."},{"w":"questionnaire","tr":"anket / soru kağıdı","te":"Noun","tt":"İsim","de":"A list of questions used to collect information","dt":"Bilgi toplamak için kullanılan sorular listesi","e1":"Please fill out this questionnaire.","e1t":"Lütfen bu anketi doldurun.","e2":"We sent the questionnaire to 500 people.","e2t":"Anketi 500 kişiye gönderdik."},{"w":"queue","tr":"kuyruk / sıraya girmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of people waiting for something","dt":"Bir şey için bekleyen insan sırası","e1":"There was a long queue at the bus stop.","e1t":"Otobüs durağında uzun bir kuyruk vardı.","e2":"We had to queue for an hour.","e2t":"Bir saat sıraya girmek zorunda kaldık."},{"w":"quick","tr":"witted","te":"kıvrak zekalı / hazırcevap","tt":"Adjective","de":"Sıfat","dt":"Able to think and understand things quickly","e1":"Şeyleri hızlıca düşünüp anlayabilen","e1t":"He is a quick","e2":"witted person.","e2t":"O kıvrak zekalı biridir."},{"w":"quietly","tr":"sessizce","te":"Adverb","tt":"Zarf","de":"Without making much noise","dt":"Çok gürültü yapmadan","e1":"He entered the room quietly.","e1t":"Odaya sessizce girdi.","e2":"Please sit quietly.","e2t":"Lütfen sessizce oturun."},{"w":"quote","tr":"alıntı yapmak / fiyat teklifi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To repeat words that someone else said","dt":"Başkasının söylediği sözleri tekrarlamak","e1":"Can you quote a famous poem?","e1t":"Ünlü bir şiirden alıntı yapabilir misin?","e2":"The contractor gave us a quote for the repairs.","e2t":"Müteahhit tamiratlar için bize bir fiyat teklifi verdi."},{"w":"racial","tr":"ırksal / ırk ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to people's race","dt":"İnsanların ırkıyla ilgili","e1":"We must fight against racial discrimination.","e1t":"Irksal ayrımcılığa karşı savaşmalıyız.","e2":"Racial equality.","e2t":"Irksal eşitlik."},{"w":"racism","tr":"ırkçılık","te":"Noun","tt":"İsim","de":"The belief that some races are better than others","dt":"Bazı ırkların diğerlerinden daha iyi olduğu inancı","e1":"Racism has no place in our society.","e1t":"Irkçılığın toplumumuzda yeri yoktur.","e2":"The victim of racism.","e2t":"Irkçılık kurbanı."},{"w":"radar","tr":"radar","te":"Noun","tt":"İsim","de":"A system for finding the position of things","dt":"Şeylerin konumunu bulma sistemi","e1":"The plane disappeared from the radar.","e1t":"Uçak radardan kayboldu.","e2":"Speed radar.","e2t":"Hız radarı."},{"w":"radiate","tr":"yaymak / ışımak","te":"Verb","tt":"Fiil","de":"To send out heat, light, or a feeling","dt":"Isı, ışık veya bir duygu yaymak","e1":"The sun radiates heat and light.","e1t":"Güneş ısı ve ışık yayar.","e2":"She radiates confidence.","e2t":"Özgüven yayıyor (etrafına özgüven aşılıyor)."},{"w":"radical","tr":"radikal / köklü / aşırı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the most important part; extreme","dt":"En önemli kısımla ilgili; aşırı","e1":"We need to make radical changes to the system.","e1t":"Sistemde köklü (radikal) değişiklikler yapmamız gerekiyor.","e2":"He has radical political views.","e2t":"Aşırı (radikal) siyasi görüşleri var."},{"w":"rage","tr":"öfke / hiddet / öfkelenmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Extreme anger that is difficult to control","dt":"Kontrol edilmesi zor aşırı öfke","e1":"He was shaking with rage.","e1t":"Öfkeden titriyordu.","e2":"The storm raged all night.","e2t":"Fırtına bütün gece şiddetle devam etti (kudurdu)."},{"w":"railway","tr":"demiryolu","te":"Noun","tt":"İsim","de":"A track for trains to travel on","dt":"Trenlerin seyahat etmesi için yol","e1":"He works for the national railway.","e1t":"Ulusal demiryolu için çalışıyor.","e2":"The railway station is in the city center.","e2t":"Demiryolu istasyonu (gar) şehir merkezindedir."},{"w":"rainbow","tr":"gökkuşağı","te":"Noun","tt":"İsim","de":"A curved line of colors in the sky after rain","dt":"Yağmurdan sonra gökyüzünde oluşan renkli kavisli çizgi","e1":"Look at the beautiful rainbow!","e1t":"Şu güzel gökkuşağına bak!","e2":"The colors of the rainbow.","e2t":"Gökkuşağının renkleri."},{"w":"rainfall","tr":"yağış / yağış miktarı","te":"Noun","tt":"İsim","de":"The amount of rain that falls","dt":"Yağan yağmur miktarı","e1":"The average annual rainfall is low here.","e1t":"Burada yıllık ortalama yağış miktarı düşüktür.","e2":"Heavy rainfall caused flooding.","e2t":"Şiddetli yağış su baskınlarına neden oldu."},{"w":"rapidly","tr":"hızla","te":"Adverb","tt":"Zarf","de":"Very quickly","dt":"Çok hızlı bir şekilde","e1":"The population is growing rapidly.","e1t":"Nüfus hızla büyüyor.","e2":"Technology is changing rapidly.","e2t":"Teknoloji hızla değişiyor."},{"w":"rarely","tr":"nadiren / seyrek","te":"Adverb","tt":"Zarf","de":"Not often","dt":"Sık değil","e1":"I rarely watch TV these days.","e1t":"Bugünlerde nadiren TV izliyorum.","e2":"He rarely loses his temper.","e2t":"Nadiren öfkesine yenik düşer."},{"w":"rating","tr":"derece / reyting / puanlama","te":"Noun","tt":"İsim","de":"A measurement of how good or popular something is","dt":"Bir şeyin ne kadar iyi veya popüler olduğunun ölçümü","e1":"The movie has a high rating on IMDb.","e1t":"Filmin IMDb'de yüksek bir puanı (derecesi) var.","e2":"TV ratings.","e2t":"Televizyon reytingleri."},{"w":"rational","tr":"rasyonel / mantıklı","te":"Adjective","tt":"Sıfat","de":"Based on clear thought and reason","dt":"Net düşünce ve mantığa dayalı","e1":"We need to make a rational decision.","e1t":"Mantıklı bir karar vermeliyiz.","e2":"Is there a rational explanation for this?","e2t":"Bunun için mantıklı bir açıklama var mı?"},{"w":"raw","tr":"çiğ / ham / işlenmemiş","te":"Adjective","tt":"Sıfat","de":"Not cooked or in a natural state","dt":"Pişmemiş veya doğal durumunda","e1":"I don't like eating raw fish.","e1t":"Çiğ balık yemeyi sevmem.","e2":"Raw materials (wood, oil, etc.).","e2t":"Hammaddeler."},{"w":"readily","tr":"kolayca / seve seve","te":"Adverb","tt":"Zarf","de":"Quickly and easily; or willingly","dt":"Hızlı ve kolayca; veya isteyerek","e1":"Information is readily available online.","e1t":"Bilgiye internetten kolayca ulaşılabiliyor.","e2":"He readily accepted the offer.","e2t":"Teklifi seve seve kabul etti."},{"w":"realistic","tr":"gerçekçi","te":"Adjective","tt":"Sıfat","de":"Based on facts and what is possible","dt":"Gerçeklere ve mümkün olana dayalı","e1":"We need to set realistic goals.","e1t":"Gerçekçi hedefler belirlemeliyiz.","e2":"Be realistic; you can't finish it in one day.","e2t":"Gerçekçi ol; bunu bir günde bitiremezsin."},{"w":"reasonable","tr":"makul / mantıklı / uygun (fiyat)","te":"Adjective","tt":"Sıfat","de":"Sensible or fair; not too expensive","dt":"Mantıklı veya adil; çok pahalı olmayan","e1":"That sounds like a reasonable suggestion.","e1t":"Bu makul bir öneri gibi geliyor.","e2":"The price is very reasonable.","e2t":"Fiyat oldukça uygun (makul)."},{"w":"reasonably","tr":"makul bir şekilde / epey","te":"Adverb","tt":"Zarf","de":"In a fair way or to a satisfactory degree","dt":"Adil bir şekilde veya tatmin edici bir derecede","e1":"He can speak English reasonably well.","e1t":"Makul derecede (epey) iyi İngilizce konuşabiliyor.","e2":"The hotel was reasonably priced.","e2t":"Otel makul fiyatlıydı."},{"w":"rebel","tr":"asi / isyancı / isyan etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Someone who fights against authority","dt":"Otoriteye karşı savaşan kişi","e1":"He was a rebel in his youth.","e1t":"Gençliğinde bir asiydi.","e2":"The citizens rebelled against the government.","e2t":"Vatandaşlar hükümete karşı isyan etti."},{"w":"rebellion","tr":"isyan / ayaklanma","te":"Noun","tt":"İsim","de":"An act of fighting against authority","dt":"Otoriteye karşı savaşma eylemi","e1":"The army crushed the rebellion.","e1t":"Ordu isyanı bastırdı.","e2":"A teenage rebellion.","e2t":"Gençlik isyanı."},{"w":"recall","tr":"hatırlamak / geri çağırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remember something or to ask to return","dt":"Bir şeyi hatırlamak veya geri dönmesini istemek","e1":"I don't recall seeing him there.","e1t":"Onu orada gördüğümü hatırlamıyorum.","e2":"The company recalled the faulty cars.","e2t":"Şirket hatalı arabaları geri çağırdı (toplattı)."},{"w":"receiver","tr":"alıcı / ahize","te":"Noun","tt":"İsim","de":"The part of a phone you hold or someone who receives","dt":"Telefonun tutulan kısmı veya teslim alan kişi","e1":"He picked up the receiver.","e1t":"Ahizeyi kaldırdı.","e2":"Satellite receiver.","e2t":"Uydu alıcısı."},{"w":"recipient","tr":"alıcı","te":"Noun","tt":"İsim","de":"A person who receives something","dt":"Bir şeyi teslim alan kişi","e1":"He was the recipient of a prestigious award.","e1t":"Prestijli bir ödülün alıcısı (sahibi) oldu.","e2":"Please write the recipient's address.","e2t":"Lütfen alıcının adresini yazın."},{"w":"recognition","tr":"tanıma / takdir / fark etme","te":"Noun","tt":"İsim","de":"The act of knowing someone or accepting their value","dt":"Birini tanıma veya değerini kabul etme eylemi","e1":"He received recognition for his hard work.","e1t":"Sıkı çalışması için takdir (tanınma) gördü.","e2":"The voice recognition system.","e2t":"Ses tanıma sistemi."},{"w":"recognize / recognise","tr":"tanımak / kabul etmek / fark etmek","te":"Verb","tt":"Fiil","de":"To know someone because you have seen them before","dt":"Daha önce gördüğünüz için birini tanımak","e1":"I didn't recognize you with your new haircut.","e1t":"Yeni saç kesiminle seni tanıyamadım.","e2":"The government recognized the new country.","e2t":"Hükümet yeni ülkeyi tanıdı (kabul etti)."},{"w":"recommendation","tr":"tavsiye / öneri","te":"Noun","tt":"İsim","de":"A suggestion that something is good","dt":"Bir şeyin iyi olduğuna dair öneri","e1":"Can you give me a book recommendation?","e1t":"Bana bir kitap tavsiyesi verebilir misin?","e2":"I followed your recommendation.","e2t":"Tavsiyene uydum."},{"w":"recovery","tr":"iyileşme / toparlanma / geri alma","te":"Noun","tt":"İsim","de":"The process of becoming healthy or successful again","dt":"Tekrar sağlıklı veya başarılı olma süreci","e1":"I wish you a speedy recovery.","e1t":"Acil şifalar (hızlı bir iyileşme) dilerim.","e2":"The economic recovery is slow.","e2t":"Ekonomik toparlanma yavaş."},{"w":"recreation","tr":"eğlence / dinlenme / rekreasyon","te":"Noun","tt":"İsim","de":"Activities that you do for enjoyment when not working","dt":"Çalışmadığınızda keyif için yaptığınız faaliyetler","e1":"The park is used for recreation.","e1t":"Park eğlence (dinlenme) için kullanılıyor.","e2":"Recreation center.","e2t":"Eğlence merkezi."},{"w":"recruit","tr":"işe almak / yeni üye / kaydetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To find new people to join a company or army","dt":"Şirket veya orduya katılacak yeni insanlar bulmak","e1":"We need to recruit more teachers.","e1t":"Daha fazla öğretmen işe almalıyız.","e2":"He is a new recruit in the army.","e2t":"O orduda yeni bir askerdir (acemidir)."},{"w":"recruitment","tr":"işe alım / yeni üye kaydı","te":"Noun","tt":"İsim","de":"The process of finding new people to join an organization","dt":"Bir organizasyona katılacak yeni insanlar bulma süreci","e1":"The recruitment process is very strict.","e1t":"İşe alım süreci çok katıdır.","e2":"He works in recruitment.","e2t":"İşe alım (insan kaynakları) alanında çalışıyor."},{"w":"reference","tr":"referans / kaynak / söz etme","te":"Noun","tt":"İsim","de":"A mention of something or a source of information","dt":"Bir şeyden söz etme veya bilgi kaynağı","e1":"Keep this for future reference.","e1t":"Bunu gelecekteki referanslar (bakmak) için sakla.","e2":"He made a reference to our previous meeting.","e2t":"Önceki toplantımıza atıfta bulundu."},{"w":"reflection","tr":"yansıma / düşünce","te":"Noun","tt":"İsim","de":"An image in a mirror or careful thought","dt":"Aynadaki görüntü veya dikkatli düşünce","e1":"I saw my reflection in the window.","e1t":"Pencerede yansımamı gördüm.","e2":"After much reflection, I decided to quit.","e2t":"Uzun düşüncelerden sonra istifa etmeye karar verdim."},{"w":"refuge","tr":"barınak / sığınak","te":"Noun","tt":"İsim","de":"A place that provides protection from danger","dt":"Tehlikeden koruma sağlayan yer","e1":"They took refuge in a cave.","e1t":"Bir mağaraya sığındılar.","e2":"Wildlife refuge.","e2t":"Yaban hayatı sığınağı."},{"w":"regard","tr":"saygı / dikkat / saymak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Respect or to consider in a particular way","dt":"Saygı veya belirli bir şekilde değerlendirmek/saymak","e1":"I have a high regard for your work.","e1t":"İşine büyük saygı duyuyorum.","e2":"He is regarded as an expert.","e2t":"Bir uzman olarak kabul edilir (sayılır)."},{"w":"regardless","tr":"ne olursa olsun / bakmaksızın","te":"Adverb","tt":"Zarf","de":"Despite everything","dt":"Her şeye rağmen","e1":"He continued regardless of the pain.","e1t":"Acıya bakmaksızın devam etti.","e2":"Everyone is welcome regardless of age.","e2t":"Yaşa bakılmaksızın herkes davetlidir."},{"w":"regional","tr":"bölgesel","te":"Adjective","tt":"Sıfat","de":"Relating to a particular region","dt":"Belirli bir bölgeyle ilgili","e1":"A regional newspaper.","e1t":"Bölgesel bir gazete.","e2":"Regional development.","e2t":"Bölgesel kalkınma."},{"w":"register","tr":"kayıt olmak / sicil / kaydetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put information into an official list","dt":"Bilgiyi resmi bir listeye koymak","e1":"You need to register for the course.","e1t":"Kursa kayıt olmanız gerekiyor.","e2":"The marriage register.","e2t":"Evlilik sicili."},{"w":"registration","tr":"kayıt / tescil","te":"Noun","tt":"İsim","de":"The act of registering","dt":"Kaydolma eylemi","e1":"Vehicle registration.","e1t":"Araç tescili (ruhsatı).","e2":"The registration fee is 50 dollars.","e2t":"Kayıt ücreti 50 dolardır."},{"w":"rehabilitation","tr":"rehabilitasyon","te":"Noun","tt":"İsim","de":"The process of being rehabilitated","dt":"Rehabilite edilme süreci","e1":"He is in a rehabilitation clinic.","e1t":"Rehabilitasyon kliniğinde.","e2":"Physical rehabilitation.","e2t":"Fiziksel rehabilitasyon."},{"w":"rejection","tr":"reddedilme / ret","te":"Noun","tt":"İsim","de":"The act of rejecting","dt":"Reddetme eylemi","e1":"He suffered a lot of rejection before finding success.","e1t":"Başarıyı bulmadan önce çok fazla ret cevabı (reddedilme) yaşadı.","e2":"Letter of rejection.","e2t":"Ret mektubu."},{"w":"relatively","tr":"nispeten / oranla","te":"Adverb","tt":"Zarf","de":"To a certain degree when compared to something else","dt":"Başka bir şeyle kıyaslandığında belirli bir derecede","e1":"The test was relatively easy.","e1t":"Test nispeten kolaydı.","e2":"He lives in a relatively small house.","e2t":"Nispeten küçük bir evde yaşıyor."},{"w":"relaxation","tr":"rahatlama / gevşeme","te":"Noun","tt":"İsim","de":"The act of relaxing","dt":"Rahatlama eylemi","e1":"Reading is my favorite form of relaxation.","e1t":"Okumak en sevdiğim rahatlama şeklidir.","e2":"Muscle relaxation exercises.","e2t":"Kas gevşetme egzersizleri."},{"w":"reliability","tr":"güvenilirlik","te":"Noun","tt":"İsim","de":"The quality of being able to be trusted","dt":"Güvenilebilir olma özelliği","e1":"I checked the reliability of the source.","e1t":"Kaynağın güvenilirliğini kontrol ettim.","e2":"Japanese cars are known for their reliability.","e2t":"Japon arabaları güvenilirlikleriyle tanınır."},{"w":"reliance","tr":"güven / bağımlılık","te":"Noun","tt":"İsim","de":"The state of depending on something","dt":"Bir şeye bağımlı olma durumu","e1":"The country's reliance on imported oil.","e1t":"Ülkenin ithal petrole olan bağımlılığı.","e2":"Reliance on technology is increasing.","e2t":"Teknolojiye olan güven (bağımlılık) artıyor."},{"w":"relieved","tr":"rahatlamış","te":"Adjective","tt":"Sıfat","de":"Happy that something unpleasant has not happened","dt":"Hoş olmayan bir şey gerçekleşmediği için mutlu","e1":"I felt relieved when the exam was over.","e1t":"Sınav bittiğinde rahatlamış hissettim.","e2":"She looked relieved to see us.","e2t":"Bizi gördüğüne rahatlamış görünüyordu."},{"w":"religious","tr":"dini / dindar","te":"Adjective","tt":"Sıfat","de":"Relating to religion or believing in a god","dt":"Dinle ilgili olan veya bir tanrıya inanan","e1":"Religious education.","e1t":"Din eğitimi.","e2":"He is a very religious person.","e2t":"O çok dindar biridir."},{"w":"rely on","tr":"güvenmek / bel bağlamak","te":"Verb","tt":"Fiil","de":"To depend on someone or something","dt":"Birine veya bir şeye bağımlı olmak (güvenmek)","e1":"You can rely on me.","e1t":"Bana güvenebilirsin.","e2":"They rely on solar energy.","e2t":"Güneş enerjisine bel bağlıyorlar (ona güveniyorlar)."},{"w":"remains","tr":"kalıntılar / ceset","te":"Noun","tt":"İsim","de":"The parts of something that are left after it has been destroyed","dt":"Bir şey yok edildikten sonra geriye kalan kısımlar","e1":"They found the remains of an ancient city.","e1t":"Antik bir şehrin kalıntılarını buldular.","e2":"The human remains were sent to the lab.","e2t":"İnsan kalıntıları (ceset parçaları) laboratuvara gönderildi."},{"w":"reminder","tr":"hatırlatıcı / hatırlatma","te":"Noun","tt":"İsim","de":"Something that makes you remember something","dt":"Bir şeyi hatırlamanızı sağlayan şey","e1":"I set a reminder on my phone.","e1t":"Telefonuma bir hatırlatıcı kurdum.","e2":"A gentle reminder about the deadline.","e2t":"Teslim tarihi hakkında nazik bir hatırlatma."},{"w":"remittance","tr":"havale / para gönderme","te":"Noun","tt":"İsim","de":"An amount of money that you send to someone","dt":"Birine gönderdiğiniz para miktarı","e1":"Please enclose the remittance with your order.","e1t":"Lütfen havaleyi siparişinizle birlikte gönderin.","e2":"Remittance of funds.","e2t":"Fonların havalesi."},{"w":"removal","tr":"çıkarma / kaldırma / taşınma","te":"Noun","tt":"İsim","de":"The act of taking something away","dt":"Bir şeyi alıp götürme veya çıkarma eylemi","e1":"The removal of the tumor was successful.","e1t":"Tümörün çıkarılması başarılıydı.","e2":"A furniture removal van.","e2t":"Mobilya taşıma kamyonu."},{"w":"renewal","tr":"yenileme","te":"Noun","tt":"İsim","de":"The act of renewing something","dt":"Bir şeyi yenileme eylemi","e1":"Passport renewal.","e1t":"Pasaport yenileme.","e2":"The renewal of the city center.","e2t":"Şehir merkezinin yenilenmesi."},{"w":"renowned","tr":"ünlü / meşhur / namlı","te":"Adjective","tt":"Sıfat","de":"Famous for something good","dt":"İyi bir şeyle tanınmış, ünlü","e1":"He is a renowned heart surgeon.","e1t":"O meşhur bir kalp cerrahıdır.","e2":"The region is renowned for its apples.","e2t":"Bölge elmalarıyla ünlüdür."},{"w":"repay","tr":"geri ödemek / karşılığını vermek","te":"Verb","tt":"Fiil","de":"To pay back money that you have borrowed","dt":"Ödünç alınan parayı geri ödemek","e1":"I'll repay the loan next month.","e1t":"Krediyi önümüzdeki ay geri ödeyeceğim.","e2":"How can I ever repay your kindness?","e2t":"İyiliğinin karşılığını nasıl ödeyebilirim?"},{"w":"repeatedly","tr":"defalarca / tekrar tekrar","te":"Adverb","tt":"Zarf","de":"Many times","dt":"Birçok kez","e1":"I've warned him repeatedly.","e1t":"Onu defalarca uyardım.","e2":"She called me repeatedly.","e2t":"Beni tekrar tekrar aradı."},{"w":"replacement","tr":"yedek / yerine geçen / değiştirme","te":"Noun","tt":"İsim","de":"Someone or something that takes the place of another","dt":"Bir başkasının yerini alan kişi veya şey","e1":"We are looking for a replacement for the manager.","e1t":"Müdürün yerine geçecek birini arıyoruz.","e2":"Replacement parts for the machine.","e2t":"Makine için yedek parçalar."},{"w":"representation","tr":"temsil / gösterim","te":"Noun","tt":"İsim","de":"The act of representing someone or something","dt":"Birini veya bir şeyi temsil etme eylemi","e1":"Our company needs better representation overseas.","e1t":"Şirketimizin yurt dışında daha iyi bir temsile ihtiyacı var.","e2":"Visual representation of data.","e2t":"Verilerin görsel gösterimi."},{"w":"representative","tr":"temsilci","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who acts for another person or group","dt":"Başka bir kişi veya grup adına hareket eden kişi","e1":"A customer service representative.","e1t":"Müşteri hizmetleri temsilcisi.","e2":"This painting is representative of his style.","e2t":"Bu tablo onun tarzının bir örneğidir (temsilcisidir)."},{"w":"reproduction","tr":"üreme / çoğaltma / kopya","te":"Noun","tt":"İsim","de":"The process of reproducing","dt":"Üreme veya kopyalama süreci","e1":"Human reproduction.","e1t":"İnsan üremesi.","e2":"This painting is a reproduction, not the original.","e2t":"Bu tablo orijinal değil, bir kopyadır."},{"w":"requirement","tr":"gereksinim / şart / ihtiyaç","te":"Noun","tt":"İsim","de":"Something that is necessary or must be done","dt":"Gerekli olan veya yapılması gereken şey","e1":"What are the entry requirements for the university?","e1t":"Üniversiteye giriş şartları (gereksinimleri) nelerdir?","e2":"Safety is a legal requirement.","e2t":"Güvenlik yasal bir zorunluluktur (şarttır)."},{"w":"residence","tr":"konut / ikametgah","te":"Noun","tt":"İsim","de":"A person's home or the fact of living in a place","dt":"Birinin evi veya bir yerde yaşama gerçeği","e1":"The Governor's official residence.","e1t":"Valinin resmi konutu.","e2":"Permanent residence.","e2t":"Sürekli ikamet (oturma izni)."},{"w":"residual","tr":"kalıntı / artık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Remaining after most of something has gone","dt":"Bir şeyin çoğu gittikten sonra geriye kalan","e1":"Residual income.","e1t":"Artık (pasif) gelir.","e2":"There is some residual heat in the oven.","e2t":"Fırında biraz kalıntı ısı var."},{"w":"resignation","tr":"istifa","te":"Noun","tt":"İsim","de":"The act of resigning","dt":"İstifa etme eylemi","e1":"He handed in his resignation.","e1t":"İstifasını sundu.","e2":"The president accepted his resignation.","e2t":"Başkan onun istifasını kabul etti."},{"w":"resistant","tr":"dayanıklı / dirençli","te":"Adjective","tt":"Sıfat","de":"Not harmed or affected by something","dt":"Bir şeyden zarar görmeyen veya etkilenmeyen","e1":"This watch is water","e1t":"resistant.","e2":"Bu saat suya dayanıklıdır.","e2t":"The bacteria are resistant to antibiotics."},{"w":"resolute","tr":"kararlı / azimli","te":"Adjective","tt":"Sıfat","de":"Determined not to change your mind","dt":"Kararını değiştirmemeye azimli olma","e1":"He remained resolute in his decision.","e1t":"Kararında azimli (kararlı) kaldı.","e2":"A resolute leader.","e2t":"Kararlı bir lider."},{"w":"respective","tr":"kendi / her birinin kendi","te":"Adjective","tt":"Sıfat","de":"Relating separately to each of the people/things mentioned","dt":"Bahsedilen her bir kişi/şeyle ayrı ayrı ilgili olan","e1":"They all went back to their respective homes.","e1t":"Hepsi kendi (ayrı ayrı) evlerine döndüler.","e2":"The respective roles of teachers and students.","e2t":"Öğretmenlerin ve öğrencilerin her birinin kendi rolleri."},{"w":"respectively","tr":"sırasıyla","te":"Adverb","tt":"Zarf","de":"In the same order as the people or things already mentioned","dt":"Zaten bahsedilen kişi veya şeylerle aynı sırada","e1":"Ali and Can are 10 and 12 years old, respectively.","e1t":"Ali ve Can sırasıyla 10 ve 12 yaşındadır.","e2":"The first and second prizes went to Ayşe and Mehmet, respectively.","e2t":"Birinci ve ikinci ödüller sırasıyla Ayşe ve Mehmet'e gitti."},{"w":"restoration","tr":"restorasyon / onarım / geri getirme","te":"Noun","tt":"İsim","de":"The act of returning something to its original condition","dt":"Bir şeyi orijinal durumuna geri getirme eylemi","e1":"The restoration of the ancient mosque took two years.","e1t":"Antik caminin restorasyonu iki yıl sürdü.","e2":"Restoration of peace.","e2t":"Barışın yeniden tesisi (geri getirilmesi)."},{"w":"restriction","tr":"kısıtlama / sınırlama","te":"Noun","tt":"İsim","de":"A rule that limits what you can do","dt":"Ne yapabileceğinizi sınırlayan kural","e1":"Import restrictions.","e1t":"İthalat kısıtlamaları.","e2":"There are no restrictions on who can join.","e2t":"Kimlerin katılabileceği konusunda bir sınırlama yoktur."},{"w":"restrictive","tr":"kısıtlayıcı / sınırlayıcı","te":"Adjective","tt":"Sıfat","de":"Limiting someone's freedom or actions","dt":"Birinin özgürlüğünü veya eylemlerini sınırlayan","e1":"These laws are too restrictive.","e1t":"Bu yasalar çok kısıtlayıcı.","e2":"A restrictive diet.","e2t":"Kısıtlayıcı bir diyet."},{"w":"result","tr":"sonuç / sonuçlanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that happens because of something else","dt":"Başka bir şey nedeniyle gerçekleşen şey","e1":"What was the result of the test?","e1t":"Testin sonucu neydi?","e2":"The accident resulted in two deaths.","e2t":"Kaza iki ölümle sonuçlandı."},{"w":"retirement","tr":"emeklilik","te":"Noun","tt":"İsim","de":"The state of being retired","dt":"Emekli olma durumu","e1":"He is enjoying his retirement.","e1t":"Emekliliğinin tadını çıkarıyor.","e2":"Retirement age.","e2t":"Emeklilik yaşı."},{"w":"revision","tr":"revizyon / gözden geçirme / tekrar (ders)","te":"Noun","tt":"İsim","de":"The act of revising something","dt":"Revize etme veya tekrar etme eylemi","e1":"The book needs a lot of revision.","e1t":"Kitabın çok fazla revizyona (düzeltmeye) ihtiyacı var.","e2":"I'm doing some revision tonight.","e2t":"Bu gece (ders) tekrarı yapıyorum."},{"w":"revival","tr":"canlanma / yeniden uyanış","te":"Noun","tt":"İsim","de":"The act of something becoming popular again","dt":"Bir şeyin tekrar popüler hale gelmesi eylemi","e1":"There is a revival of interest in folk music.","e1t":"Halk müziğine olan ilgide bir canlanma var.","e2":"Economic revival.","e2t":"Ekonomik canlanma."},{"w":"revolutionary","tr":"devrimci / devrim niteliğinde","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a revolution or completely new","dt":"Devrimle ilgili veya tamamen yeni","e1":"A revolutionary new discovery.","e1t":"Devrim niteliğinde yeni bir keşif.","e2":"He was a famous revolutionary.","e2t":"O ünlü bir devrimciydi."},{"w":"rinse","tr":"durulamak / çalkalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To wash something with clean water only","dt":"Bir şeyi sadece temiz suyla yıkamak","e1":"Rinse the dishes before putting them in the dishwasher.","e1t":"Bulaşıkları makineye koymadan önce durulayın.","e2":"Give your mouth a quick rinse.","e2t":"Ağzını hızlıca bir çalkala."},{"w":"risky","tr":"riskli / tehlikeli","te":"Adjective","tt":"Sıfat","de":"Dangerous or uncertain","dt":"Tehlikeli veya belirsiz","e1":"Investing all your money is very risky.","e1t":"Tüm paranı yatırmak çok risklidir.","e2":"It was a risky decision to leave his job.","e2t":"İşinden ayrılmak riskli bir karardı."},{"w":"rivalry","tr":"rekabet / çekişme","te":"Noun","tt":"İsim","de":"Competition between two people or groups","dt":"İki kişi veya grup arasındaki rekabet","e1":"There is a friendly rivalry between the brothers.","e1t":"Kardeşler arasında dostça bir rekabet var.","e2":"Political rivalry.","e2t":"Siyasi rekabet."},{"w":"robbery","tr":"soygun","te":"Noun","tt":"İsim","de":"The crime of stealing from a person or place","dt":"Bir kişiden veya yerden çalma suçu","e1":"Armed robbery.","e1t":"Silahlı soygun.","e2":"The police are investigating the robbery.","e2t":"Polis soygunu araştırıyor."},{"w":"romantic","tr":"romantik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to love or a feeling of excitement","dt":"Aşkla veya heyecan duygusuyla ilgili","e1":"We had a romantic dinner.","e1t":"Romantik bir akşam yemeği yedik.","e2":"He is not a very romantic person.","e2t":"O pek romantik biri değildir."},{"w":"roommate","tr":"oda arkadaşı","te":"Noun","tt":"İsim","de":"A person you share a room or apartment with","dt":"Odayı veya daireyi paylaştığınız kişi","e1":"He is my roommate at university.","e1t":"O üniversitedeki oda arkadaşım.","e2":"I am looking for a new roommate.","e2t":"Yeni bir oda arkadaşı arıyorum."},{"w":"rotation","tr":"dönüş / rotasyon / devir","te":"Noun","tt":"İsim","de":"The act of rotating","dt":"Dönme eylemi","e1":"The rotation of the Earth.","e1t":"Dünya'nın dönüşü.","e2":"Staff rotation.","e2t":"Personel rotasyonu (değişimi)."},{"w":"rotten","tr":"çürük / kokuşmuş / berbat","te":"Adjective","tt":"Sıfat","de":"Decayed or very bad","dt":"Çürümüş veya çok kötü","e1":"The apples are rotten.","e1t":"Elmalar çürük.","e2":"I feel rotten about what happened.","e2t":"Olanlar hakkında kendimi berbat hissediyorum."},{"w":"roughly","tr":"kabaca / yaklaşık olarak","te":"Adverb","tt":"Zarf","de":"Approximately or in a rough way","dt":"Yaklaşık olarak veya kaba bir şekilde","e1":"There were roughly 200 people.","e1t":"Kabaca (yaklaşık) 200 kişi vardı.","e2":"He pushed me roughly.","e2t":"Beni kabaca itti."},{"w":"royalty","tr":"kraliyet ailesi / telif hakkı","te":"Noun","tt":"İsim","de":"Members of a royal family or a payment to an author","dt":"Kraliyet ailesi üyeleri veya yazara yapılan ödeme","e1":"He behaved like royalty.","e1t":"Kraliyet ailesindenmiş gibi davrandı.","e2":"She receives royalties from her books.","e2t":"Kitaplarından telif hakkı (ücreti) alıyor."},{"w":"rubber","tr":"kauçuk / lastik / silgi (UK)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A strong, waterproof material or an eraser","dt":"Güçlü, su geçirmez malzeme veya silgi","e1":"The tires are made of rubber.","e1t":"Lastikler kauçuktan (lastikten) yapılmıştır.","e2":"Can I borrow your rubber?","e2t":"Silgini ödünç alabilir miyim?"},{"w":"run out","tr":"tükenmek / bitmek","te":"Verb","tt":"Fiil","de":"To have no more of something","dt":"Bir şeyin kalmaması","e1":"We have run out of milk.","e1t":"Sütümüz bitti (tükendi).","e2":"Time is running out.","e2t":"Zaman tükeniyor."},{"w":"rusty","tr":"paslı / körelmiş (beceri)","te":"Adjective","tt":"Sıfat","de":"Covered with rust or out of practice","dt":"Pasla kaplı veya pratik yapmamaktan dolayı zayıflamış","e1":"Be careful, the nail is rusty.","e1t":"Dikkat et, çivi paslı.","e2":"My English is a bit rusty.","e2t":"İngilizcem biraz körelmiş (eskisi kadar iyi değil)."},{"w":"sadness","tr":"üzüntü / keder","te":"Noun","tt":"İsim","de":"The state of being sad","dt":"Üzgün olma durumu","e1":"Her eyes were full of sadness.","e1t":"Gözleri üzüntü doluydu.","e2":"It is with great sadness that I tell you this.","e2t":"Bunu size büyük bir üzüntüyle söylüyorum."},{"w":"safeguard","tr":"korumak / güvence altına almak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To protect something from harm or loss","dt":"Bir şeyi zarardan veya kayıptan korumak","e1":"We must safeguard the environment for future generations.","e1t":"Gelecek nesiller için çevreyi korumalıyız.","e2":"The new law is a safeguard against fraud.","e2t":"Yeni yasa dolandırıcılığa karşı bir güvencedir."},{"w":"sailor","tr":"denizci","te":"Noun","tt":"İsim","de":"A person who works on a ship","dt":"Gemide çalışan kişi","e1":"He is an experienced sailor.","e1t":"O deneyimli bir denizcidir.","e2":"The sailors were happy to reach the land.","e2t":"Denizciler karaya ulaştıkları için mutluydu."},{"w":"sales","tr":"satış / satışlar","te":"Noun","tt":"İsim","de":"The number of goods or services sold","dt":"Satılan mal veya hizmet sayısı","e1":"Sales have increased this year.","e1t":"Satışlar bu yıl arttı.","e2":"He works in the sales department.","e2t":"Satış departmanında çalışıyor."},{"w":"sane","tr":"akli dengesi yerinde / mantıklı","te":"Adjective","tt":"Sıfat","de":"Mentally healthy or sensible","dt":"Zihinsel olarak sağlıklı veya mantıklı","e1":"No sane person would do that.","e1t":"Aklı başında hiçbir insan bunu yapmaz.","e2":"He is trying to stay sane in this chaos.","e2t":"Bu kaosun içinde aklını korumaya (sağlıklı kalmaya) çalışıyor."},{"w":"satisfactorily","tr":"tatmin edici bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that is good enough","dt":"Yeterince iyi bir şekilde","e1":"The matter has been settled satisfactorily.","e1t":"Mesele tatmin edici bir şekilde halledildi.","e2":"He performed the task satisfactorily.","e2t":"Görevi tatmin edici bir şekilde yerine getirdi."},{"w":"satisfied","tr":"memnun / tatmin olmuş","te":"Adjective","tt":"Sıfat","de":"Pleased because you have what you wanted","dt":"İstediğinize sahip olduğunuz için hoşnut","e1":"Are you satisfied with the service?","e1t":"Hizmetten memnun musunuz?","e2":"A satisfied customer.","e2t":"Memnun bir müşteri."},{"w":"satisfy","tr":"memnun etmek / tatmin etmek / karşılamak","te":"Verb","tt":"Fiil","de":"To please someone or to meet a requirement","dt":"Birini hoşnut etmek veya bir gereksinimi karşılamak","e1":"It is difficult to satisfy everyone.","e1t":"Herkesi memnun etmek zordur.","e2":"This meal will satisfy your hunger.","e2t":"Bu yemek açlığını yatıştıracaktır (karşılayacaktır)."},{"w":"saucer","tr":"fincan tabağı","te":"Noun","tt":"İsim","de":"A small curved plate that you put a cup on","dt":"Üzerine fincan koyduğunuz küçük kavisli tabak","e1":"A cup and saucer.","e1t":"Fincan ve tabağı.","e2":"He spilled some tea into the saucer.","e2t":"Tabağa biraz çay döktü."},{"w":"saving","tr":"tasarruf / birikim","te":"Noun","tt":"İsim","de":"The act of keeping money or using less of something","dt":"Para tutma veya bir şeyi daha az kullanma eylemi","e1":"Energy saving.","e1t":"Enerji tasarrufu.","e2":"I put all my savings into the bank.","e2t":"Tüm birikimlerimi bankaya yatırdım."},{"w":"scanner","tr":"tarayıcı","te":"Noun","tt":"İsim","de":"A machine that scans something","dt":"Bir şeyi tarayan makine","e1":"I need to put the document in the scanner.","e1t":"Belgeyi tarayıcıya koymam gerekiyor.","e2":"Fingerprint scanner.","e2t":"Parmak izi tarayıcı."},{"w":"scar","tr":"yara izi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A mark left on the skin after an injury","dt":"Yaralanmadan sonra ciltte kalan iz","e1":"He has a scar on his forehead.","e1t":"Alnında bir yara izi var.","e2":"The accident left a scar on her face.","e2t":"Kaza yüzünde bir yara izi bıraktı."},{"w":"scarcely","tr":"neredeyse hiç / güçbela","te":"Adverb","tt":"Zarf","de":"Only just or almost not","dt":"Sadece veya neredeyse hiç","e1":"I could scarcely believe it.","e1t":"Buna neredeyse hiç inanamadım (inanması çok güçtü).","e2":"There were scarcely 50 people there.","e2t":"Orada güçbela (ancak) 50 kişi vardı."},{"w":"scared","tr":"korkmuş","te":"Adjective","tt":"Sıfat","de":"Frightened","dt":"Korkmuş","e1":"I'm scared of spiders.","e1t":"Örümceklerden korkarım.","e2":"She looked scared.","e2t":"Korkmuş görünüyordu."},{"w":"school e","tr":"register","te":"okul e","tt":"okul / okul e","de":"kayıt","dt":"Noun","e1":"İsim","e1t":"A digital system for school records","e2":"Okul kayıtları için dijital sistem","e2t":"We use the school e"},{"w":"scientific","tr":"bilimsel","te":"Adjective","tt":"Sıfat","de":"Relating to science","dt":"Bilimle ilgili","e1":"Scientific research.","e1t":"Bilimsel araştırma.","e2":"There is no scientific evidence for this.","e2t":"Bunun için bilimsel bir kanıt yok."},{"w":"scissors","tr":"makas","te":"Noun","tt":"İsim","de":"A tool used for cutting paper or cloth","dt":"Kağıt veya kumaş kesmek için kullanılan araç","e1":"Where are the scissors?","e1t":"Makas nerede?","e2":"A pair of scissors.","e2t":"Bir makas."},{"w":"scuba diving","tr":"tüplü dalış","te":"Noun","tt":"İsim","de":"The activity of swimming underwater using a tank of air","dt":"Hava tüpü kullanarak su altında yüzme faaliyeti","e1":"I enjoy scuba diving in the Mediterranean.","e1t":"Akdeniz'de tüplü dalış yapmaktan zevk alırım.","e2":"Scuba diving gear.","e2t":"Tüplü dalış ekipmanı."},{"w":"sculptor","tr":"heykeltıraş","te":"Noun","tt":"İsim","de":"A person who makes sculptures","dt":"Heykel yapan kişi","e1":"He is a world","e1t":"famous sculptor.","e2":"O dünyaca ünlü bir heykeltıraştır.","e2t":"The sculptor worked with marble."},{"w":"seashell","tr":"deniz kabuğu","te":"Noun","tt":"Isim","de":"The empty shell of a small sea creature","dt":"Küçük bir deniz canlısının boş kabuğu","e1":"The children are collecting seashells on the beach.","e1t":"Çocuklar plajda deniz kabuğu topluyor.","e2":"A necklace made of seashells.","e2t":"Deniz kabuklarından yapılmış bir kolye."},{"w":"seeker","tr":"arayan / peşinde olan","te":"Noun","tt":"İsim","de":"A person who is looking for something","dt":"Bir şeyi arayan kişi","e1":"Job seeker.","e1t":"İş arayan kişi.","e2":"Asylum seeker (someone seeking protection).","e2t":"Sığınmacı."},{"w":"segregation","tr":"ayrım / tecrit / ayrıştırma","te":"Noun","tt":"İsim","de":"The act of keeping things or people separate","dt":"Şeyleri veya insanları ayrı tutma eylemi","e1":"Racial segregation.","e1t":"Irk ayrımı.","e2":"The segregation of waste.","e2t":"Atıkların ayrıştırılması."},{"w":"seize","tr":"ele geçirmek / yakalamak / el koymak","te":"Verb","tt":"Fiil","de":"To take hold of something suddenly or by force","dt":"Bir şeyi aniden veya zorla tutmak","e1":"The police seized the drugs.","e1t":"Polis uyuşturuculara el koydu.","e2":"Seize the opportunity!","e2t":"Fırsatı yakala!"},{"w":"self","tr":"confidence","te":"özgüven","tt":"Noun","de":"İsim","dt":"Belief in your own ability and value","e1":"Kendi yeteneğine ve değerine olan inanç","e1t":"You need more self","e2":"confidence.","e2t":"Daha fazla özgüvene ihtiyacın var."},{"w":"self","tr":"conscious","te":"çekingen / kendinden utanan","tt":"Adjective","de":"Sıfat","dt":"Nervous or uncomfortable about what people think of you","e1":"İnsanların hakkınızda ne düşündüğü konusunda gergin veya rahatsız","e1t":"He felt self","e2":"conscious in his new suit.","e2t":"Yeni takım elbisesinin içinde kendini çekingen (herkes ona bakıyormuş gibi) hissetti."},{"w":"self","tr":"control","te":"otokontrol / özdenetim","tt":"Noun","de":"İsim","dt":"The ability to control your emotions and behavior","e1":"Duygularını ve davranışlarını kontrol etme yeteneği","e1t":"You need to show some self","e2":"control.","e2t":"Biraz otokontrol göstermelisin."},{"w":"self","tr":"evident","te":"bariz / apaçık","tt":"Adjective","de":"Sıfat","dt":"Obvious and needing no proof","e1":"Kanıta ihtiyaç duymayan, bariz","e1t":"It is self","e2":"evident that we need to save energy.","e2t":"Enerji tasarrufu yapmamız gerektiği apaçıktır."},{"w":"selfish","tr":"bencil","te":"Adjective","tt":"Sıfat","de":"Caring only about yourself","dt":"Sadece kendini düşünen","e1":"Don't be so selfish!","e1t":"Bu kadar bencil olma!","e2":"A selfish act.","e2t":"Bencilce bir eylem."},{"w":"selfishness","tr":"bencillik","te":"Noun","tt":"İsim","de":"The quality of being selfish","dt":"Bencil olma özelliği","e1":"His selfishness destroyed the friendship.","e1t":"Onun bencilliği arkadaşlığı bitirdi.","e2":"Pure selfishness.","e2t":"Tamamen bencillik."},{"w":"seller","tr":"satıcı","te":"Noun","tt":"İsim","de":"A person who sells something","dt":"Bir şey satan kişi","e1":"He is a used car seller.","e1t":"O bir ikinci el araba satıcısıdır.","e2":"Best seller (a popular book).","e2t":"En çok satan (kitap)."},{"w":"semi","tr":"final","te":"yarı final","tt":"Noun","de":"İsim","dt":"One of the two games that decide who will be in the final","e1":"Finale kimin çıkacağına karar veren iki maçtan biri","e1t":"Turkey reached the semi","e2":"final in 2002.","e2t":"Türkiye 2002'de yarı finale yükseldi."},{"w":"semicolon","tr":"noktalı virgül","te":"Noun","tt":"İsim","de":"A punctuation mark (;) used to separate parts of a sentence","dt":"Cümle parçalarını ayırmak için kullanılan noktalama işareti (;)","e1":"You can use a semicolon to connect two independent clauses.","e1t":"İki bağımsız cümleyi bağlamak için noktalı virgül kullanabilirsiniz.","e2":"The use of the semicolon.","e2t":"Noktalı virgül kullanımı."},{"w":"senator","tr":"senatör","te":"Noun","tt":"İsim","de":"A member of a senate","dt":"Senato üyesi","e1":"He was elected as a senator.","e1t":"Senatör olarak seçildi.","e2":"The senator gave a speech.","e2t":"Senatör bir konuşma yaptı."},{"w":"sensible","tr":"mantıklı / akıllıca","te":"Adjective","tt":"Sıfat","de":"Showing good judgment; practical","dt":"İyi bir muhakeme gösteren; pratik/akılcı","e1":"That sounds like a sensible suggestion.","e1t":"Bu mantıklı bir öneri gibi geliyor.","e2":"Be sensible and wear a coat.","e2t":"Mantıklı ol ve bir palto giy."},{"w":"sensitive","tr":"hassas / duyarlı","te":"Adjective","tt":"Sıfat","de":"Easily upset or able to understand others' feelings","dt":"Kolayca üzülen veya başkalarının duygularını anlayabilen","e1":"He is very sensitive to criticism.","e1t":"Eleştiriye karşı çok hassastır.","e2":"Sensitive skin.","e2t":"Hassas cilt."},{"w":"sensitivity","tr":"hassasiyet / duyarlılık","te":"Noun","tt":"İsim","de":"The quality of being sensitive","dt":"Hassas olma özelliği","e1":"The sensitivity of the camera.","e1t":"Kameranın hassasiyeti.","e2":"Cultural sensitivity.","e2t":"Kültürel duyarlılık."},{"w":"sentiment","tr":"duygu / düşünce / hassasiyet","te":"Noun","tt":"İsim","de":"An opinion or a feeling of gentleness","dt":"Bir görüş veya nazik bir duygu (duyumsama)","e1":"Public sentiment is against the new law.","e1t":"Kamuoyu düşüncesi yeni yasaya karşı.","e2":"I share your sentiments.","e2t":"Duygularınızı (görüşlerinizi) paylaşıyorum."},{"w":"separately","tr":"ayrı ayrı","te":"Adverb","tt":"Zarf","de":"Not together","dt":"Birlikte değil","e1":"The two issues must be discussed separately.","e1t":"İki konu ayrı ayrı tartışılmalıdır.","e2":"They arrived separately.","e2t":"Ayrı ayrı geldiler."},{"w":"separation","tr":"ayrılık / ayrılma","te":"Noun","tt":"İsim","de":"The act of moving apart","dt":"Ayrılma eylemi","e1":"The separation of church and state.","e1t":"Din ve devlet işlerinin ayrılması.","e2":"Their separation lasted for two years.","e2t":"Ayrılıkları iki yıl sürdü."},{"w":"seriously","tr":"ciddi bir şekilde","te":"Adverb","tt":"Zarf","de":"In a serious way","dt":"Ciddi bir biçimde","e1":"He was seriously injured in the accident.","e1t":"Kazada ağır (ciddi) yaralandı.","e2":"I seriously doubt it.","e2t":"Bundan ciddi şekilde şüphe duyuyorum."},{"w":"seriousness","tr":"ciddiyet","te":"Noun","tt":"İsim","de":"The state of being serious","dt":"Ciddi olma durumu","e1":"I don't think you realize the seriousness of the situation.","e1t":"Durumun ciddiyetini fark ettiğini sanmıyorum.","e2":"The seriousness of the disease.","e2t":"Hastalığın ciddiyeti (ağırlığı)."},{"w":"serve","tr":"hizmet etmek / servis yapmak / yaramak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To provide food; to work for an organization; to be useful","dt":"Yemek sağlamak; bir kuruluş için çalışmak; yararlı olmak","e1":"They serve breakfast until 10 AM.","e1t":"Saat 10'a kadar kahvaltı servisi yapıyorlar.","e2":"He served in the army for two years.","e2t":"İki yıl orduda hizmet etti (askerlik yaptı)."},{"w":"settled","tr":"yerleşik / kararlaştırılmış","te":"Adjective","tt":"Sıfat","de":"Established or decided","dt":"Kurulmuş veya kararlaştırılmış","e1":"He has a settled life now.","e1t":"Artık yerleşik (düzenli) bir hayatı var.","e2":"The matter is settled.","e2t":"Mesele halloldu (karara bağlandı)."},{"w":"settlement","tr":"yerleşim / anlaşma / ödeme","te":"Noun","tt":"İsim","de":"A place where people live or an official agreement","dt":"İnsanların yaşadığı yer veya resmi anlaşma","e1":"An ancient settlement.","e1t":"Antik bir yerleşim yeri.","e2":"They reached a legal settlement.","e2t":"Yasal bir anlaşmaya vardılar."},{"w":"settler","tr":"yerleşimci","te":"Noun","tt":"İsim","de":"A person who goes to live in a new place","dt":"Yeni bir yere yaşamaya giden kişi","e1":"The early settlers in America.","e1t":"Amerika'daki ilk yerleşimciler.","e2":"European settlers.","e2t":"Avrupalı yerleşimciler."},{"w":"severely","tr":"şiddetle / ağır bir şekilde","te":"Adverb","tt":"Zarf","de":"In a very serious or strict way","dt":"Çok ciddi veya katı bir şekilde","e1":"He was severely punished.","e1t":"Ağır bir şekilde cezalandırıldı.","e2":"The project was severely delayed.","e2t":"Proje şiddetle (ciddi şekilde) gecikti."},{"w":"severity","tr":"şiddet / ciddiyet / sertlik","te":"Noun","tt":"İsim","de":"The quality of being severe","dt":"Şiddetli veya ciddi olma özelliği","e1":"The severity of the accident.","e1t":"Kazanın şiddeti (ciddiyeti).","e2":"We were surprised by the severity of his words.","e2t":"Sözlerinin sertliği karşısında şaşırdık."},{"w":"sew","tr":"dikmek","te":"Verb","tt":"Fiil","de":"To join pieces of cloth using a needle and thread","dt":"İğne ve iplik kullanarak kumaş parçalarını birleştirmek","e1":"She is learning how to sew.","e1t":"Nasıl dikiş dikileceğini öğreniyor.","e2":"I need to sew a button on my shirt.","e2t":"Gömleğime bir düğme dikmem gerekiyor."},{"w":"sewing","tr":"dikiş / dikiş dikme","te":"Noun","tt":"İsim","de":"The activity of joining pieces of cloth","dt":"Kumaş parçalarını birleştirme faaliyeti","e1":"She enjoys sewing in her free time.","e1t":"Boş zamanlarında dikiş dikmekten zevk alır.","e2":"A sewing machine.","e2t":"Dikiş makinesi."},{"w":"shaft","tr":"şaft / sap / kuyu (maden)","te":"Noun","tt":"İsim","de":"A long, thin handle or a vertical opening","dt":"Uzun, ince sap veya dikey açıklık","e1":"A shaft of light.","e1t":"Bir ışık huzmesi (şaftı).","e2":"Elevator shaft.","e2t":"Asansör boşluğu."},{"w":"shame","tr":"utanç / yazık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of being upset about something wrong","dt":"Yanlış bir şey hakkında duyulan üzüntü hissi","e1":"He felt no shame for what he did.","e1t":"Yaptığı şey için hiç utanç duymadı.","e2":"It's a shame that you can't come.","e2t":"Gelememen ne yazık (ne ayıp)."},{"w":"shampoo","tr":"şampuan / şampuanlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A liquid used for washing hair","dt":"Saç yıkamak için kullanılan sıvı","e1":"Use a mild shampoo.","e1t":"Yumuşak bir şampuan kullanın.","e2":"I need to shampoo the carpet.","e2t":"Halıyı şampuanlamam (yıkamam) gerekiyor."},{"w":"shareholder","tr":"hissedar","te":"Noun","tt":"İsim","de":"A person who owns shares in a company","dt":"Bir şirkette hissesi olan kişi","e1":"The company held a meeting for its shareholders.","e1t":"Şirket hissedarları için bir toplantı düzenledi.","e2":"Majority shareholder.","e2t":"Çoğunluk hissedarı."},{"w":"sharpen","tr":"keskinleştirmek / bilemek","te":"Verb","tt":"Fiil","de":"To make something sharp or sharper","dt":"Bir şeyi keskin veya daha keskin hale getirmek","e1":"I need to sharpen my pencil.","e1t":"Kalemimi açmam (sivriltmem) gerekiyor.","e2":"Use a stone to sharpen the knife.","e2t":"Bıçağı bilemek için bir taş kullan."},{"w":"shave","tr":"tıraş olmak / tıraş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cut hair very close to the skin","dt":"Kılları cilde çok yakın bir yerden kesmek","e1":"He shaves every morning.","e1t":"Her sabah tıraş olur.","e2":"I need a shave.","e2t":"Tıraş olmam lazım."},{"w":"shear","tr":"kırkmak / kesmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cut the wool off a sheep","dt":"Bir koyunun yününü kesmek","e1":"It's time to shear the sheep.","e1t":"Koyunları kırkma vakti.","e2":"Shear strength (technical term).","e2t":"Kayma mukavemeti (teknik terim)."},{"w":"shed","tr":"dökmek / kulübe / kurtulmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To lose hair or leaves; a small building for storage","dt":"Tüy veya yaprak dökmek; depolama için küçük bina","e1":"Trees shed their leaves in autumn.","e1t":"Ağaçlar sonbaharda yapraklarını döker.","e2":"I keep my tools in the garden shed.","e2t":"Aletlerimi bahçe kulübesinde tutuyorum."},{"w":"shepherd","tr":"çoban / rehberlik etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who looks after sheep","dt":"Koyunlara bakan kişi","e1":"The shepherd led the flock to the pasture.","e1t":"Çoban sürüyü meraya götürdü.","e2":"He shepherded the guests into the room.","e2t":"Misafirlere odaya kadar rehberlik etti."},{"w":"shiny","tr":"parlak","te":"Adjective","tt":"Sıfat","de":"Bright and smooth","dt":"Parlak ve pürüzsüz","e1":"A shiny new car.","e1t":"Parlak yeni bir araba.","e2":"Shiny hair.","e2t":"Parlak saçlar."},{"w":"ship","tr":"gemi / nakletmek / göndermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large boat or to send goods","dt":"Büyük tekne veya malları göndermek","e1":"The ship arrived at the port.","e1t":"Gemi limana ulaştı.","e2":"The company will ship your order tomorrow.","e2t":"Şirket siparişinizi yarın kargolayacak (gönderecek)."},{"w":"shipping","tr":"nakliye / deniz taşımacılığı","te":"Noun","tt":"İsim","de":"The act of sending goods; or ships as a group","dt":"Malların gönderilmesi eylemi; veya grup olarak gemiler","e1":"Free shipping.","e1t":"Ücretsiz nakliye.","e2":"A major shipping lane.","e2t":"Önemli bir nakliye yolu."},{"w":"shocked","tr":"şok olmuş / sarsılmış","te":"Adjective","tt":"Sıfat","de":"Very surprised and upset","dt":"Çok şaşırmış ve üzülmüş","e1":"We were shocked to hear about the accident.","e1t":"Kazayı duyduğumuzda şok olduk.","e2":"She looked shocked.","e2t":"Şok olmuş görünüyordu."},{"w":"shocking","tr":"şok edici / sarsıcı","te":"Adjective","tt":"Sıfat","de":"Very surprising or very bad","dt":"Çok şaşırtıcı veya çok kötü","e1":"It was a shocking news.","e1t":"Şok edici bir haberdi.","e2":"The conditions in the prison were shocking.","e2t":"Hapishanedeki koşullar şok ediciydi."},{"w":"shooting","tr":"ateş etme / çekim (film)","te":"Noun","tt":"İsim","de":"The act of firing a gun or filming","dt":"Silah ateşleme veya film çekme eylemi","e1":"There was a shooting in the city center.","e1t":"Şehir merkezinde bir silahlı saldırı (ateş etme olayı) oldu.","e2":"Shooting of the film begins next week.","e2t":"Filmin çekimleri haftaya başlıyor."},{"w":"shopkeeper","tr":"dükkan sahibi / esnaf","te":"Noun","tt":"İsim","de":"A person who owns or manages a shop","dt":"Bir dükkana sahip olan veya yöneten kişi","e1":"The local shopkeeper is very friendly.","e1t":"Yerel esnaf çok arkadaş canlısıdır.","e2":"He has been a shopkeeper for 30 years.","e2t":"30 yıldır dükkan işletiyor."},{"w":"shore","tr":"kıyı / sahil","te":"Noun","tt":"İsim","de":"The land along the edge of a sea or lake","dt":"Deniz veya göl kenarındaki kara parçası","e1":"The boat reached the shore.","e1t":"Tekne kıyıya ulaştı.","e2":"We walked along the shore.","e2t":"Kıyı boyunca yürüdük."},{"w":"shortly","tr":"kısa süre içinde / yakında","te":"Adverb","tt":"Zarf","de":"Soon","dt":"Yakında","e1":"The plane will land shortly.","e1t":"Uçak kısa süre içinde inecek.","e2":"I'll be with you shortly.","e2t":"Birazdan (kısa süre içinde) yanında olacağım."},{"w":"shortsighted","tr":"uzağı göremeyen / öngörüsüz","te":"Adjective","tt":"Sıfat","de":"Unable to see far or not thinking about the future","dt":"Uzağı göremeyen veya geleceği düşünmeyen","e1":"He is shortsighted and needs glasses.","e1t":"O uzağı göremiyor ve gözlüğe ihtiyacı var.","e2":"A shortsighted policy.","e2t":"Öngörüsüz bir politika."},{"w":"shot","tr":"atış / kare (fotoğraf) / aşı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The act of firing a gun or a photograph","dt":"Silah ateşleme eylemi veya fotoğraf karesi","e1":"He fired a shot into the air.","e1t":"Havaya bir el ateş etti.","e2":"That was a great shot of the sunset.","e2t":"Gün batımının harika bir karesiydi."},{"w":"shout","tr":"bağırmak / haykırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak very loudly","dt":"Çok yüksek sesle konuşmak","e1":"Don't shout at me!","e1t":"Bana bağırma!","e2":"I heard a shout for help.","e2t":"Yardım için bir haykırış duydum."},{"w":"shovel","tr":"kürek / küremek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool used for digging or moving soil/snow","dt":"Kazmak veya toprak/kar taşımak için kullanılan araç","e1":"He used a shovel to clear the snow.","e1t":"Karı temizlemek için kürek kullandı.","e2":"Shovel the soil into the bin.","e2t":"Toprağı kürekle kovaya doldur."},{"w":"show off","tr":"gösteriş yapmak / hava atmak","te":"Verb","tt":"Fiil","de":"To try to impress others with your abilities/possessions","dt":"Yeteneklerin veya sahip olduklarınla başkalarını etkilemeye çalışmak","e1":"He likes to show off his new car.","e1t":"Yeni arabasıyla hava atmayı (gösteriş yapmayı) sever.","e2":"Stop showing off!","e2t":"Gösteriş yapmayı bırak!"},{"w":"show up","tr":"çıkagelmek / görünmek","te":"Verb","tt":"Fiil","de":"To arrive or appear somewhere","dt":"Bir yere varmak veya orada görünmek","e1":"He didn't show up for the meeting.","e1t":"Toplantıya gelmedi (çıkagelmedi).","e2":"I hope he shows up soon.","e2t":"Umarım yakında görünür (gelir)."},{"w":"shrill","tr":"tiz / keskin (ses)","te":"Adjective/Verb","tt":"Having a high, sharp, and unpleasant sound","de":"Yüksek, keskin ve hoş olmayan ses","dt":"A shrill whistle.","e1":"Tiz bir düdük sesi.","e1t":"Her voice was shrill.","e2":"Sesi tizdi (kulak tırmalayıcıydı).","e2t":""},{"w":"shrimp","tr":"karides","te":"Noun","tt":"İsim","de":"A small sea animal with a shell and many legs","dt":"Kabuklu ve çok bacaklı küçük bir deniz hayvanı","e1":"I ordered grilled shrimp.","e1t":"Izgara karides sipariş ettim.","e2":"Shrimp cocktail.","e2t":"Karides kokteyl."},{"w":"shut down","tr":"kapatmak / durdurmak","te":"Verb","tt":"Fiil","de":"To stop a machine or a business from operating","dt":"Bir makineyi veya bir işi durdurmak","e1":"The factory was shut down last year.","e1t":"Fabrika geçen yıl kapatıldı.","e2":"Shut down the computer.","e2t":"Bilgisayarı kapat."},{"w":"sickness","tr":"hastalık / mide bulantısı","te":"Noun","tt":"İsim","de":"The state of being ill or the feeling of wanting to vomit","dt":"Hasta olma durumu veya kusma isteği hissi","e1":"Sea sickness.","e1t":"Deniz tutması (mide bulantısı).","e2":"She suffered from a long sickness.","e2t":"Uzun süren bir hastalık çekti."},{"w":"sideways","tr":"yan / yanlamasına","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Towards or from the side","dt":"Yan tarafa doğru veya yan taraftan","e1":"He took a sideways glance at me.","e1t":"Bana yan bir bakış attı.","e2":"The crab moves sideways.","e2t":"Yengeç yanlamasına hareket eder."},{"w":"sightseeing","tr":"turistik yerleri gezme","te":"Noun","tt":"İsim","de":"The activity of visiting interesting places as a tourist","dt":"Turist olarak ilginç yerleri ziyaret etme faaliyeti","e1":"We did a lot of sightseeing in Paris.","e1t":"Paris'te bol bol turistik yerleri gezdik.","e2":"A sightseeing tour.","e2t":"Turistik gezi turu."},{"w":"significantly","tr":"önemli ölçüde","te":"Adverb","tt":"Zarf","de":"In a way that is easy to notice or important","dt":"Fark edilmesi kolay veya önemli bir şekilde","e1":"Profits have increased significantly.","e1t":"Kârlar önemli ölçüde arttı.","e2":"The situation has improved significantly.","e2t":"Durum önemli ölçüde gelişti."},{"w":"signify","tr":"anlamına gelmek / belirtmek","te":"Verb","tt":"Fiil","de":"To be a sign of something or to mean","dt":"Bir şeyin işareti olmak veya anlamına gelmek","e1":"What does this symbol signify?","e1t":"Bu sembol ne anlama geliyor?","e2":"A red light signifies danger.","e2t":"Kırmızı ışık tehlikeyi belirtir."},{"w":"silent","tr":"sessiz","te":"Adjective","tt":"Sıfat","de":"Without any sound","dt":"Hiç ses çıkarmayan","e1":"Keep the phone on silent mode.","e1t":"Telefonu sessiz modda tutun.","e2":"He remained silent during the meeting.","e2t":"Toplantı sırasında sessiz kaldı."},{"w":"silk","tr":"ipek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A delicate, soft type of fabric made from worms","dt":"Tırtıllardan yapılan hassas, yumuşak kumaş türü","e1":"This tie is made of pure silk.","e1t":"Bu kravat saf ipekten yapılmıştır.","e2":"Silk road.","e2t":"İpek yolu."},{"w":"silly","tr":"aptalca / saçma","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not serious or sensible; stupid","dt":"Ciddi veya mantıklı olmayan; aptalca","e1":"Don't be so silly!","e1t":"Bu kadar saçma (çocuksu/aptalca) davranma!","e2":"A silly mistake.","e2t":"Aptalca bir hata."},{"w":"similarity","tr":"benzerlik","te":"Noun","tt":"İsim","de":"The state of being similar","dt":"Benzer olma durumu","e1":"I can see the similarity between the two brothers.","e1t":"İki kardeş arasındaki benzerliği görebiliyorum.","e2":"There are many similarities.","e2t":"Birçok benzerlik var."},{"w":"similarly","tr":"benzer şekilde","te":"Adverb","tt":"Zarf","de":"In a similar way","dt":"Benzer bir biçimde","e1":"The second experiment was conducted similarly.","e1t":"İkinci deney benzer şekilde yürütüldü.","e2":"You must dress similarly for the interview.","e2t":"Mülakat için benzer şekilde (uygun) giyinmelisin."},{"w":"simple","tr":"basit / sade","te":"Adjective","tt":"Sıfat","de":"Not complicated or easy to understand","dt":"Karmaşık olmayan veya anlaması kolay","e1":"This is a simple question.","e1t":"Bu basit bir sorudur.","e2":"The machine is simple to use.","e2t":"Makinenin kullanımı basittir."},{"w":"simplicity","tr":"basitlik / sadelik","te":"Noun","tt":"İsim","de":"The quality of being simple","dt":"Basit olma özelliği","e1":"I admire the simplicity of the design.","e1t":"Tasarımın sadeliğine hayranım.","e2":"For the sake of simplicity...","e2t":"Basitlik (anlaşılırlık) hatırına..."},{"w":"simply","tr":"sadece / basitçe / düpedüz","te":"Adverb","tt":"Zarf","de":"Only or in a simple way","dt":"Sadece veya basit bir şekilde","e1":"It is simply a matter of time.","e1t":"Bu sadece bir zaman meselesidir.","e2":"He explained it very simply.","e2t":"Onu çok basitçe açıkladı."},{"w":"simulate","tr":"simüle etmek / taklit etmek","te":"Verb","tt":"Fiil","de":"To create a model or to pretend to feel something","dt":"Bir model oluşturmak veya bir şeyi hissediyormuş gibi yapmak","e1":"The computer program simulates a flight.","e1t":"Bilgisayar programı bir uçuşu simüle ediyor.","e2":"He simulated an illness to avoid the exam.","e2t":"Sınava girmemek için hastalık taklidi yaptı."},{"w":"simulation","tr":"simülasyon / taklit","te":"Noun","tt":"İsim","de":"The act of simulating something","dt":"Bir şeyi simüle etme eylemi","e1":"Flight simulation.","e1t":"Uçuş simülasyonu.","e2":"A computer simulation of the accident.","e2t":"Kazanın bilgisayar simülasyonu."},{"w":"simultaneously","tr":"eşzamanlı olarak","te":"Adverb","tt":"Zarf","de":"At the same time","dt":"Aynı anda","e1":"The two movies were released simultaneously.","e1t":"İki film eşzamanlı olarak vizyona girdi.","e2":"You can't do two things simultaneously.","e2t":"İki şeyi aynı anda yapamazsın."},{"w":"sincerely","tr":"içtenlikle / samimiyetle","te":"Adverb","tt":"Zarf","de":"In a sincere way","dt":"Samimi bir şekilde","e1":"I sincerely hope you succeed.","e1t":"Başarılı olmanı içtenlikle umuyorum.","e2":"Yours sincerely (formal letter ending).","e2t":"Saygılarımla (mektup kapanışı)."},{"w":"situate","tr":"yerleştirmek / konumlandırmak","te":"Verb","tt":"Fiil","de":"To put something in a particular position","dt":"Bir şeyi belirli bir konuma koymak","e1":"The house is situated on a hill.","e1t":"Ev bir tepenin üzerine konumlandırılmıştır.","e2":"They situated the factory near the river.","e2t":"Fabrikayı nehir yakınına yerleştirdiler."},{"w":"skilled","tr":"vasıflı / becerikli / uzman","te":"Adjective","tt":"Sıfat","de":"Having the necessary skills or training","dt":"Gerekli becerilere veya eğitime sahip olan","e1":"A skilled worker.","e1t":"Vasıflı (kalifiye) işçi.","e2":"He is very skilled at playing the guitar.","e2t":"Gitar çalma konusunda çok yeteneklidir."},{"w":"slash","tr":"kesik / yarmak / eğik çizgi (/)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long cut or to cut something with a sharp blade","dt":"Uzun bir kesik veya keskin bir bıçakla kesmek","e1":"The prices were slashed by 50%.","e1t":"Fiyatlar %50 oranında indirildi (kesildi).","e2":"Forward slash.","e2t":"Taksim işareti (/)."},{"w":"slave","tr":"köle","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who is owned by another person","dt":"Başka birinin mülkiyetinde olan kişi","e1":"He worked like a slave.","e1t":"Köle gibi çalıştı.","e2":"Slave trade.","e2t":"Köle ticareti."},{"w":"slavery","tr":"kölelik","te":"Noun","tt":"İsim","de":"The state of being a slave","dt":"Köle olma durumu","e1":"The abolition of slavery.","e1t":"Köleliğin kaldırılması.","e2":"Modern slavery.","e2t":"Modern kölelik."},{"w":"sleeve","tr":"kol (giysi) / kılıf","te":"Noun","tt":"İsim","de":"The part of a piece of clothing that covers some or all of the arm","dt":"Kıyafetin kolun bir kısmını veya tamamını örten bölümü","e1":"Short sleeves.","e1t":"Kısa kollar.","e2":"I have an ace up my sleeve (a secret advantage).","e2t":"Gizli bir avantajım (kozum) var."},{"w":"slightly","tr":"hafifçe / biraz","te":"Adverb","tt":"Zarf","de":"A little bit","dt":"Birazcık","e1":"I am slightly worried about the results.","e1t":"Sonuçlar hakkında hafifçe endişeliyim.","e2":"The price is slightly higher than I expected.","e2t":"Fiyat beklediğimden biraz daha yüksek."},{"w":"small","tr":"scale","te":"küçük ölçekli","tt":"Adjective","de":"Sıfat","dt":"Not involving many people or things; limited","e1":"Çok fazla insan veya şeyi içermeyen; sınırlı","e1t":"A small","e2":"scale business.","e2t":"Küçük ölçekli bir işletme."},{"w":"smoothly","tr":"pürüzsüzce / sorunsuz bir şekilde","te":"Adverb","tt":"Zarf","de":"Without any problems or in a smooth way","dt":"Hiçbir sorun olmadan veya pürüzsüz bir şekilde","e1":"The meeting went smoothly.","e1t":"Toplantı sorunsuz (pürüzsüzce) geçti.","e2":"The car runs smoothly.","e2t":"Araba sarsıntısız (düzgün) çalışıyor."},{"w":"smuggler","tr":"kaçakçı","te":"Noun","tt":"İsim","de":"A person who smuggles goods","dt":"Mal kaçıran (kaçakçılık yapan) kişi","e1":"The police arrested the diamond smuggler.","e1t":"Polis elmas kaçakçısını tutukladı.","e2":"Arms smuggler.","e2t":"Silah kaçakçısı."},{"w":"so","tr":"called","te":"sözde / denilen","tt":"Adjective","de":"Sıfat","dt":"Used to show that you think a name is not correct","e1":"Bir ismin doğru olmadığını düşündüğünüzü göstermek için kullanılır","e1t":"My so","e2":"called friend betrayed me.","e2t":"Sözde arkadaşım bana ihanet etti."},{"w":"socialism","tr":"sosyalizm","te":"Noun","tt":"İsim","de":"A political system based on public ownership","dt":"Kamu mülkiyetine dayalı siyasi sistem","e1":"He believes in the principles of socialism.","e1t":"Sosyalizmin ilkelerine inanıyor.","e2":"Democratic socialism.","e2t":"Demokratik sosyalizm."},{"w":"socialist","tr":"sosyalist","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who supports socialism","dt":"Sosyalizmi destekleyen kişi","e1":"He joined the socialist party.","e1t":"Sosyalist partiye katıldı.","e2":"A socialist country.","e2t":"Sosyalist bir ülke."},{"w":"socket","tr":"priz / soket / yuva","te":"Noun","tt":"İsim","de":"A place where something fits in or a part of a plug system","dt":"Bir şeyin içine oturduğu yer veya fiş sisteminin parçası","e1":"Put the plug into the socket.","e1t":"Fişi prize (sokete) tak.","e2":"Eye socket.","e2t":"Göz çukuru (yuvası)."},{"w":"soften","tr":"yumuşatmak / gevşemek","te":"Verb","tt":"Fiil","de":"To become less hard, strong, or severe","dt":"Daha az sert, güçlü veya şiddetli hale gelmek","e1":"Boil the carrots until they soften.","e1t":"Havuçları yumuşayana kadar kaynatın.","e2":"His voice softened.","e2t":"Sesi yumuşadı."},{"w":"solely","tr":"sadece / yalnızca","te":"Adverb","tt":"Zarf","de":"Only and not involving anyone or anything else","dt":"Sadece ve başka kimseyi/şeyi içermeden","e1":"He is solely responsible for the project.","e1t":"Projeden yalnızca o sorumlu.","e2":"The decision was based solely on merit.","e2t":"Karar sadece liyakate dayalıydı."},{"w":"solid","tr":"katı / sağlam / somut","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not liquid or gas; strong and reliable","dt":"Sıvı veya gaz olmayan; güçlü ve güvenilir","e1":"Ice is solid water.","e1t":"Buz, suyun katı halidir.","e2":"We have solid evidence.","e2t":"Somut (sağlam) kanıtlarımız var."},{"w":"somewhat","tr":"biraz / bir miktar","te":"Adverb","tt":"Zarf","de":"To some degree","dt":"Bir dereceye kadar","e1":"The situation is somewhat complicated.","e1t":"Durum biraz (bir miktar) karmaşık.","e2":"I was somewhat surprised by the news.","e2t":"Haberlere biraz şaşırdım."},{"w":"sophistication","tr":"gelişmişlik / karmaşıklık / kültürlülük","te":"Noun","tt":"İsim","de":"The quality of being sophisticated","dt":"Gelişmiş veya kültürlü olma özelliği","e1":"The sophistication of modern technology.","e1t":"Modern teknolojinin gelişmişliği.","e2":"Her style has a certain sophistication.","e2t":"Tarzının belli bir kültürel derinliği (inceliği) var."},{"w":"southeast","tr":"güneydoğu","te":"Noun/Adjective/Adverb","tt":"The direction between south and east","de":"Güney ile doğu arasındaki yön","dt":"The wind is coming from the southeast.","e1":"Rüzgar güneydoğudan geliyor.","e1t":"Southeast Asia.","e2":"Güneydoğu Asya.","e2t":""},{"w":"southwest","tr":"güneybatı","te":"Noun/Adjective/Adverb","tt":"The direction between south and west","de":"Güney ile batı arasındaki yön","dt":"They live in the southwest of the city.","e1":"Şehrin güneybatısında yaşıyorlar.","e1t":"Southwest England.","e2":"Güneybatı İngiltere.","e2t":""},{"w":"spare","tr":"yedek / ayırmak / kıymamak","te":"Adjective/Verb/Noun","tt":"Extra or to give time/money","de":"Ekstra veya zaman/para vermek","dt":"A spare tire.","e1":"Yedek lastik.","e1t":"Can you spare a few minutes?","e2":"Birkaç dakikanızı ayırabilir misiniz?","e2t":""},{"w":"sparrow","tr":"serçe","te":"Noun","tt":"İsim","de":"A small common brown bird","dt":"Küçük, yaygın kahverengi kuş","e1":"I saw a sparrow on the window.","e1t":"Pencerede bir serçe gördüm.","e2":"Sparrows are very social birds.","e2t":"Serçeler çok sosyal kuşlardır."},{"w":"specialized / specialised","tr":"özelleşmiş / uzmanlaşmış","te":"Adjective","tt":"Sıfat","de":"Designed for a particular purpose","dt":"Belirli bir amaç için tasarlanmış","e1":"Specialized training.","e1t":"Özelleşmiş (uzmanlık gerektiren) eğitim.","e2":"Specialized equipment.","e2t":"Özel ekipman."},{"w":"specialty / speciality","tr":"uzmanlık alanı / özellik","te":"Noun","tt":"İsim","de":"A subject or activity that you know a lot about","dt":"Çok şey bildiğiniz bir konu veya faaliyet","e1":"Fish is the restaurant's specialty.","e1t":"Balık restoranın spesiyali (özelliği).","e2":"My specialty is educational technology.","e2t":"Uzmanlık alanım eğitim teknolojisidir."},{"w":"specifically","tr":"özellikle / net olarak","te":"Adverb","tt":"Zarf","de":"For a particular purpose or in a clear way","dt":"Belirli bir amaç için veya net bir şekilde","e1":"This book was written specifically for children.","e1t":"Bu kitap özellikle çocuklar için yazıldı.","e2":"I specifically told you not to do that.","e2t":"Sana bunu yapmamanı net olarak söyledim."},{"w":"speculation","tr":"spekülasyon / tahmin","te":"Noun","tt":"İsim","de":"The act of guessing without full information","dt":"Tam bilgi olmadan tahmin yürütme eylemi","e1":"There has been a lot of speculation about his future.","e1t":"Geleceği hakkında çok fazla spekülasyon yapıldı.","e2":"Pure speculation.","e2t":"Tamamen spekülasyon (varsayım)."},{"w":"spell","tr":"hecelemek / büyü / kısa süre","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say the letters of a word; or magic; or a short period","dt":"Bir kelimenin harflerini söylemek; veya büyü; veya kısa süre","e1":"How do you spell your name?","e1t":"Adını nasıl hecelersin?","e2":"A cold spell (a short period of cold weather).","e2t":"Soğuk hava dalgası (kısa bir süre)."},{"w":"spelling","tr":"heceleme / yazım","te":"Noun","tt":"İsim","de":"The correct way of writing a word","dt":"Bir kelimenin doğru yazılma biçimi","e1":"My spelling is not very good.","e1t":"Yazımım (imlam) pek iyi değil.","e2":"Spelling mistake.","e2t":"Yazım hatası."},{"w":"spicy","tr":"baharatlı / acılı","te":"Adjective","tt":"Sıfat","de":"Having a strong, hot flavor","dt":"Güçlü, acı (yakıcı) bir tada sahip","e1":"Do you like spicy food?","e1t":"Baharatlı (acılı) yemek sever misin?","e2":"A spicy sauce.","e2t":"Acılı bir sos."},{"w":"sponsorship","tr":"sponsorluk","te":"Noun","tt":"İsim","de":"The act of sponsoring","dt":"Sponsor olma eylemi","e1":"The team is looking for corporate sponsorship.","e1t":"Takım kurumsal sponsorluk arıyor.","e2":"Under the sponsorship of...","e2t":"... sponsorluğu altında."},{"w":"sporty","tr":"sportif / spor seven","te":"Adjective","tt":"Sıfat","de":"Enjoying sport or relating to sport","dt":"Spor yapmaktan zevk alan veya sporla ilgili","e1":"She is a very sporty person.","e1t":"O çok sportif biridir.","e2":"A sporty car.","e2t":"Spor (görünümlü) bir araba."},{"w":"spouse","tr":"eş (karı veya koca)","te":"Noun","tt":"İsim","de":"A person's husband or wife","dt":"Bir kişinin kocası veya karısı","e1":"You can bring your spouse to the party.","e1t":"Partiye eşinizi getirebilirsiniz.","e2":"Spouse's name.","e2t":"Eşin adı."},{"w":"spy","tr":"casus / casusluk yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who secretly gets information","dt":"Gizlice bilgi toplayan kişi","e1":"He was arrested as a spy.","e1t":"Casus olarak tutuklandı.","e2":"I spy with my little eye...","e2t":"Gözüme bir şey ilişti (oyun)."},{"w":"squalor","tr":"sefillik / pislik","te":"Noun","tt":"İsim","de":"The state of being extremely dirty and unpleasant","dt":"Aşırı kirli ve nahoş olma durumu","e1":"They lived in extreme squalor.","e1t":"Aşırı sefalet (pislik) içinde yaşıyorlardı.","e2":"The squalor of the slums.","e2t":"Gecekonduların sefilliği."},{"w":"stainless","tr":"paslanmaz / lekesiz","te":"Adjective","tt":"Sıfat","de":"Not able to be stained or rusted","dt":"Paslanmayan veya leke tutmayan","e1":"Stainless steel.","e1t":"Paslanmaz çelik.","e2":"Stainless reputation.","e2t":"Lekesiz (tertemiz) itibar."},{"w":"stand by","tr":"desteklemek / hazırda beklemek","te":"Verb","tt":"Fiil","de":"To support someone or to be ready to act","dt":"Birini desteklemek veya harekete hazır beklemek","e1":"I will stand by you no matter what.","e1t":"Ne olursa olsun senin yanında duracağım (seni destekleyeceğim).","e2":"The police are standing by.","e2t":"Polis hazırda bekliyor."},{"w":"standing","tr":"ayakta duran / konum / saygınlık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Being in a vertical position or status","dt":"Dikey konumda olma veya statü","e1":"He has a high standing in the community.","e1t":"Toplumda yüksek bir saygınlığı (konumu) var.","e2":"A standing ovation.","e2t":"Ayakta alkışlama."},{"w":"stare","tr":"dik dik bakmak / dikizlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look at someone for a long time","dt":"Birine uzun süre bakmak","e1":"Don't stare at people, it's rude.","e1t":"İnsanlara dik dik bakma, kabalıktır.","e2":"She gave me a cold stare.","e2t":"Bana soğuk bir bakış attı."},{"w":"starfish","tr":"denizyıldızı","te":"Noun","tt":"İsim","de":"A flat star","dt":"shaped sea creature","e1":"Yıldız şeklinde düz deniz canlısı","e1t":"We found a starfish on the beach.","e2":"Plajda bir denizyıldızı bulduk.","e2t":"Starfish can grow back their arms."},{"w":"starvation","tr":"açlık / açlıktan ölme","te":"Noun","tt":"İsim","de":"The state of having no food","dt":"Hiç yiyeceği olmama durumu","e1":"They died of starvation.","e1t":"Açlıktan öldüler.","e2":"Starvation wages (very low pay).","e2t":"Karın tokluğuna (çok düşük) ücretler."},{"w":"starve","tr":"açlıktan ölmek / çok acıkmak","te":"Verb","tt":"Fiil","de":"To suffer or die from lack of food","dt":"Yiyecek yokluğundan acı çekmek veya ölmek","e1":"Millions of people are starving.","e1t":"Milyonlarca insan açlık çekiyor (açlıktan ölüyor).","e2":"I'm starving! (I am very hungry).","e2t":"Açlıktan ölüyorum! (Çok acıktım)."},{"w":"state","tr":"devlet / eyalet / durum / belirtmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A country; a condition; or to say officially","dt":"Ülke; durum; veya resmi olarak söylemek","e1":"What is your marital state?","e1t":"Medeni durumun nedir?","e2":"Please state your name and occupation.","e2t":"Lütfen adınızı ve mesleğinizi belirtin."},{"w":"statistic","tr":"istatistik / istatistiksel veri","te":"Noun","tt":"İsim","de":"A fact in the form of a number","dt":"Sayı formundaki gerçek/bilgi","e1":"This is a shocking statistic.","e1t":"Bu şok edici bir istatistiktir.","e2":"Crime statistics.","e2t":"Suç istatistikleri."},{"w":"statistical","tr":"istatistiksel","te":"Adjective","tt":"Sıfat","de":"Relating to statistics","dt":"İstatistiklerle ilgili","e1":"Statistical analysis.","e1t":"İstatistiksel analiz.","e2":"We need statistical evidence.","e2t":"İstatistiksel kanıta ihtiyacımız var."},{"w":"stay up","tr":"uyanık kalmak / yatmamak","te":"Verb","tt":"Fiil","de":"To go to bed later than usual","dt":"Normalden daha geç yatmak","e1":"I stayed up late to watch the match.","e1t":"Maçı izlemek için geç saate kadar oturdum (yatmadım).","e2":"Don't stay up too late.","e2t":"Çok geçe kalma."},{"w":"steadily","tr":"istikrarla / düzenli bir şekilde","te":"Adverb","tt":"Zarf","de":"Gradually and regularly","dt":"Kademeli ve düzenli olarak","e1":"The population is increasing steadily.","e1t":"Nüfus düzenli bir şekilde artıyor.","e2":"He worked steadily all afternoon.","e2t":"Tüm öğleden sonra aralıksız (istikrarla) çalıştı."},{"w":"step mother","tr":"üvey anne","te":"Noun","tt":"İsim","de":"The woman who has married your father","dt":"Babanızla evlenen kadın","e1":"My stepmother is a teacher.","e1t":"Üvey annem bir öğretmendir.","e2":"She has a good relationship with her stepmother.","e2t":"Üvey annesiyle iyi bir ilişkisi var."},{"w":"stepfather","tr":"üvey baba","te":"Noun","tt":"İsim","de":"The man who has married your mother","dt":"Annenizle evlenen adam","e1":"His stepfather treated him well.","e1t":"Üvey babası ona iyi davrandı.","e2":"He lives with his mother and stepfather.","e2t":"Annesi ve üvey babasıyla yaşıyor."},{"w":"stew","tr":"yahni / türlü / dert etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Meat and vegetables cooked slowly in liquid","dt":"Sıvı içinde yavaşça pişirilen et ve sebze","e1":"Beef stew.","e1t":"Dana yahni.","e2":"He is in a stew about the exam.","e2t":"Sınav için dertleniyor (endişeli)."},{"w":"stockholder","tr":"hissedar","te":"Noun","tt":"İsim","de":"A person who owns shares in a company","dt":"Bir şirkette hissesi olan kişi","e1":"The stockholders are meeting today.","e1t":"Hissedarlar bugün toplanıyor.","e2":"Majority stockholder.","e2t":"Çoğunluk hissedarı."},{"w":"stopover","tr":"mola / aktarma durağı","te":"Noun","tt":"İsim","de":"A short stay in a place on a long journey","dt":"Uzun bir yolculukta bir yerde yapılan kısa konaklama","e1":"We had a two","e1t":"day stopover in Dubai.","e2":"Dubai'de iki günlük bir mola (duraklama) verdik.","e2t":"A brief stopover."},{"w":"straighten","tr":"düzeltmek / doğrultmak","te":"Verb","tt":"Fiil","de":"To make or become straight","dt":"Düz hale getirmek veya gelmek","e1":"She straightened her hair.","e1t":"Saçlarını düzeltti.","e2":"Straighten your tie.","e2t":"Kravatını düzelt."},{"w":"straightforward","tr":"açık / net / dürüst / basit","te":"Adjective","tt":"Sıfat","de":"Easy to understand or honest","dt":"Anlaması kolay veya dürüst","e1":"The process is quite straightforward.","e1t":"Süreç oldukça basit (net).","e2":"He is a straightforward person.","e2t":"O dürüst (açık sözlü) biridir."},{"w":"straw","tr":"saman / pipet","te":"Noun","tt":"İsim","de":"Dried stems of wheat; a thin tube for drinking","dt":"Kurutulmuş buğday sapları; içmek için kullanılan ince tüp","e1":"Can I have a straw for my juice?","e1t":"Meyve suyum için bir pipet alabilir miyim?","e2":"A hat made of straw.","e2t":"Samandan yapılmış bir şapka."},{"w":"stream","tr":"dere / akış / akım","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small river or a continuous flow","dt":"Küçük nehir veya sürekli akış","e1":"We sat by a small stream.","e1t":"Küçük bir derenin kenarında oturduk.","e2":"Live stream (video).","e2t":"Canlı yayın (akışı)."},{"w":"strengthen","tr":"güçlendirmek","te":"Verb","tt":"Fiil","de":"To make something stronger","dt":"Bir şeyi daha güçlü hale getirmek","e1":"This exercise will strengthen your muscles.","e1t":"Bu egzersiz kaslarını güçlendirecek.","e2":"We need to strengthen our relationship.","e2t":"İlişkimizi güçlendirmeliyiz."},{"w":"strictly","tr":"kesinlikle / tam olarak / sadece","te":"Adverb","tt":"Zarf","de":"Exactly or only","dt":"Tam olarak veya sadece","e1":"This information is strictly confidential.","e1t":"Bu bilgi kesinlikle gizlidir.","e2":"He followed the rules strictly.","e2t":"Kurallara tam olarak uydu."},{"w":"stripe","tr":"çizgi / şerit","te":"Noun","tt":"İsim","de":"A long narrow line of a different color","dt":"Farklı renkte uzun dar çizgi","e1":"A shirt with blue and white stripes.","e1t":"Mavi beyaz çizgili bir gömlek.","e2":"Zebras have stripes.","e2t":"Zebraların çizgileri vardır."},{"w":"stuck","tr":"sıkışmış / takılmış","te":"Adjective","tt":"Sıfat","de":"Unable to move or get out of a situation","dt":"Hareket edemeyen veya bir durumdan çıkamayan","e1":"The car is stuck in the mud.","e1t":"Araba çamura saplandı (sıkıştı).","e2":"I'm stuck on this question.","e2t":"Bu soruda takıldım."},{"w":"student","tr":"centered","te":"öğrenci merkezli","tt":"Adjective","de":"Sıfat","dt":"Focusing on the needs and interests of students","e1":"Öğrencilerin ihtiyaç ve ilgi alanlarına odaklanan","e1t":"We use student","e2":"centered learning platforms.","e2t":"Öğrenci merkezli öğrenme platformları kullanıyoruz."},{"w":"stunning","tr":"büyüleyici / şahane / şok edici","te":"Adjective","tt":"Sıfat","de":"Extremely beautiful or very surprising","dt":"Son derece güzel veya çok şaşırtıcı","e1":"The view from the top is stunning.","e1t":"Tepeden manzara büyüleyici (şahane).","e2":"A stunning victory.","e2t":"Çarpıcı (şok edici) bir zafer."},{"w":"stupid","tr":"aptal / saçma","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not intelligent or sensible","dt":"Zeki veya mantıklı olmayan","e1":"It was a stupid mistake.","e1t":"Aptalca bir hataydı.","e2":"Don't be stupid!","e2t":"Aptal olma!"},{"w":"stupidity","tr":"aptallık / saçmalık","te":"Noun","tt":"İsim","de":"The state of being stupid","dt":"Aptal olma durumu","e1":"I can't believe his stupidity.","e1t":"Onun aptallığına inanamıyorum.","e2":"It's sheer stupidity.","e2t":"Bu düpedüz aptallık."},{"w":"stylist","tr":"stilist / tarz danışmanı","te":"Noun","tt":"İsim","de":"A person whose job is to create styles","dt":"İşi tarz yaratmak olan kişi","e1":"Hair stylist.","e1t":"Saç stilisti (kuaför).","e2":"Fashion stylist.","e2t":"Moda stilisti."},{"w":"stylize / stylise","tr":"stilize etmek / belli bir tarza uydurmak","te":"Verb","tt":"Fiil","de":"To represent something in a particular artistic style","dt":"Bir şeyi belirli bir sanatsal tarzda temsil etmek","e1":"The trees are stylized in this painting.","e1t":"Bu tabloda ağaçlar stilize edilmiş.","e2":"A stylized design.","e2t":"Stilize edilmiş bir tasarım."},{"w":"subconscious","tr":"bilinçaltı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Relating to thoughts and feelings you are not aware of","dt":"Farkında olmadığınız düşünce ve duygularla ilgili","e1":"Subconscious mind.","e1t":"Bilinçaltı zihni.","e2":"A subconscious fear.","e2t":"Bilinçaltı bir korku."},{"w":"subjectivity","tr":"öznellik / subjektiflik","te":"Noun","tt":"İsim","de":"The quality of being subjective","dt":"Öznel olma özelliği","e1":"We must avoid subjectivity in the report.","e1t":"Raporda öznellikten kaçınmalıyız.","e2":"The subjectivity of art.","e2t":"Sanatın öznelliği."},{"w":"submit","tr":"sunmak / boyun eğmek / teslim etmek","te":"Verb","tt":"Fiil","de":"To give a document for consideration; to accept authority","dt":"Değerlendirme için belge vermek; otoriteyi kabul etmek","e1":"Please submit your application online.","e1t":"Lütfen başvurunuzu çevrimiçi sunun (teslim edin).","e2":"He refused to submit to their demands.","e2t":"Onların taleplerine boyun eğmeyi reddetti."},{"w":"subscriber","tr":"abone","te":"Noun","tt":"İsim","de":"A person who pays for a service","dt":"Bir hizmet için ödeme yapan kişi","e1":"The magazine has 5,000 subscribers.","e1t":"Derginin 5.000 abonesi var.","e2":"New subscribers will get a discount.","e2t":"Yeni aboneler indirim alacaklar."},{"w":"subscription","tr":"abonelik","te":"Noun","tt":"İsim","de":"An agreement to receive something regularly","dt":"Düzenli olarak bir şeyi alma anlaşması","e1":"Monthly subscription.","e1t":"Aylık abonelik.","e2":"Annual subscription fee.","e2t":"Yıllık abonelik ücreti."},{"w":"subsequently","tr":"sonradan / sonraları","te":"Adverb","tt":"Zarf","de":"Later; after something else has happened","dt":"Daha sonra; başka bir şey olduktan sonra","e1":"He was subsequently arrested.","e1t":"Sonradan tutuklandı.","e2":"The error was subsequently corrected.","e2t":"Hata sonradan düzeltildi."},{"w":"subsidize / subsidise","tr":"sübvanse etmek / desteklemek","te":"Verb","tt":"Fiil","de":"To give money to help pay for something","dt":"Bir şeyin ödenmesine yardımcı olmak için para vermek","e1":"Public transport is subsidized by the government.","e1t":"Toplu taşıma devlet tarafından sübvanse ediliyor (destekleniyor).","e2":"A subsidized meal.","e2t":"İndirimli (desteklenen) yemek."},{"w":"substantially","tr":"önemli ölçüde / büyük oranda","te":"Adverb","tt":"Zarf","de":"By a large amount","dt":"Büyük miktarda","e1":"The cost has increased substantially.","e1t":"Maliyet önemli ölçüde arttı.","e2":"The two plans are substantially different.","e2t":"İki plan büyük oranda farklı."},{"w":"substitution","tr":"yerine koyma / oyuncu değişikliği","te":"Noun","tt":"İsim","de":"The act of using someone or something instead of another","dt":"Bir başkasının yerine birini/bir şeyi kullanma eylemi","e1":"Substitution of players.","e1t":"Oyuncu değişikliği.","e2":"There is no substitution for hard work.","e2t":"Sıkı çalışmanın yerini hiçbir şey tutamaz (yerine koyma olmaz)."},{"w":"subtract","tr":"çıkarmak (matematik)","te":"Verb","tt":"Fiil","de":"To take a number away from another number","dt":"Bir sayıyı diğerinden çıkarmak","e1":"If you subtract 5 from 10, you get 5.","e1t":"10'dan 5'i çıkarırsanız 5 elde edersiniz.","e2":"Subtraction is the opposite of addition.","e2t":"Çıkarma, toplamanın zıttıdır."},{"w":"suburban","tr":"banliyöye ait / şehir dışı","te":"Adjective","tt":"Sıfat","de":"Relating to a suburb","dt":"Banliyö ile ilgili","e1":"Suburban life.","e1t":"Banliyö hayatı.","e2":"A suburban area.","e2t":"Banliyö bölgesi."},{"w":"subvert","tr":"devirmek / bozmak / yıkmak","te":"Verb","tt":"Fiil","de":"To try to destroy or damage a system or belief","dt":"Bir sistemi veya inancı yıkmaya veya zarar vermeye çalışmak","e1":"They were accused of trying to subvert the government.","e1t":"Hükümeti devirmeye çalışmakla suçlandılar.","e2":"To subvert the democratic process.","e2t":"Demokratik süreci bozmak (baltalamak)."},{"w":"sudden","tr":"ani / birdenbire","te":"Adjective","tt":"Sıfat","de":"Happening quickly and unexpectedly","dt":"Hızlı ve beklenmedik bir şekilde gerçekleşen","e1":"A sudden change in the weather.","e1t":"Hava durumunda ani bir değişiklik.","e2":"His death was very sudden.","e2t":"Ölümü çok ani oldu."},{"w":"sue","tr":"dava açmak","te":"Verb","tt":"Fiil","de":"To take legal action against someone","dt":"Birine karşı yasal işlem başlatmak","e1":"She sued the company for damages.","e1t":"Tazminat için şirkete dava açtı.","e2":"He is threatening to sue us.","e2t":"Bize dava açmakla tehdit ediyor."},{"w":"suffering","tr":"acı / keder / çile","te":"Noun","tt":"İsim","de":"Physical or mental pain","dt":"Fiziksel veya zihinsel acı","e1":"War causes a lot of human suffering.","e1t":"Savaş çok fazla insanı acıya (kedere) boğar.","e2":"To end the suffering of the poor.","e2t":"Fakirlerin çilesine son vermek."},{"w":"suffice","tr":"yetmek / kafi gelmek","te":"Verb","tt":"Fiil","de":"To be enough","dt":"Yeterli olmak","e1":"A simple \"sorry\" will suffice.","e1t":"Basit bir \"özür dilerim\" kafi gelecektir (yetecektir).","e2":"One example will suffice to illustrate the point.","e2t":"Konuyu açıklamak için bir örnek yetecektir."},{"w":"sufficiency","tr":"yeterlilik / kafi miktar","te":"Noun","tt":"İsim","de":"An amount of something that is enough","dt":"Bir şeyin yeterli olan miktarı","e1":"A sufficiency of resources.","e1t":"Kaynakların yeterliliği.","e2":"Self","e2t":"sufficiency (independence)."},{"w":"sufficient","tr":"yeterli / kafi","te":"Adjective","tt":"Sıfat","de":"Enough for a particular purpose","dt":"Belirli bir amaç için yeterli","e1":"We have sufficient evidence to prove it.","e1t":"Bunu kanıtlamak için yeterli delilimiz var.","e2":"Sufficient time.","e2t":"Yeterli zaman."},{"w":"sufficiently","tr":"yeterince / yeterli derecede","te":"Adverb","tt":"Zarf","de":"Enough","dt":"Yeterince","e1":"He was sufficiently recovered to return to work.","e1t":"İşe dönecek kadar (yeterince) iyileşmişti.","e2":"Make sure the meat is sufficiently cooked.","e2t":"Etin yeterince piştiğinden emin olun."},{"w":"suffix","tr":"son ek","te":"Noun","tt":"İsim","de":"A letter or group of letters added to the end of a word","dt":"Bir kelimenin sonuna eklenen harf veya harf grubu","e1":"The suffix \"","e1t":"ly\" is used to form adverbs.","e2":"\"","e2t":"ly\" son eki zarf türetmek için kullanılır."},{"w":"suggest","tr":"önermek / tavsiye etmek / belirtmek (ima)","te":"Verb","tt":"Fiil","de":"To mention an idea or plan for consideration","dt":"Değerlendirme için bir fikir veya plan belirtmek","e1":"I suggest that we leave early.","e1t":"Erken ayrılmamızı öneriyorum.","e2":"The evidence suggests that he is lying.","e2t":"Kanıtlar onun yalan söylediğini belirtiyor (ima ediyor)."},{"w":"suicidal","tr":"intihara meyilli / intiharla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to or intending to kill oneself","dt":"Kendini öldürme niyetiyle veya bununla ilgili olan","e1":"Suicidal thoughts.","e1t":"İntihar düşünceleri.","e2":"He made a suicidal gesture.","e2t":"İntihara meyilli bir harekette bulundu."},{"w":"suitably","tr":"uygun bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that is right for a particular situation","dt":"Belirli bir durum için doğru olan şekilde","e1":"He was suitably dressed for the interview.","e1t":"Mülakat için uygun bir şekilde giyinmişti.","e2":"Suitably impressed.","e2t":"Uygun (beklenen) derecede etkilenmiş."},{"w":"suitcase","tr":"bavul / valiz","te":"Noun","tt":"İsim","de":"A rectangular case for carrying clothes while traveling","dt":"Seyahat ederken kıyafet taşımak için kullanılan dikdörtgen çanta","e1":"I packed my suitcase last night.","e1t":"Bavulumu dün gece topladım.","e2":"He carried two heavy suitcases.","e2t":"İki ağır bavul taşıdı."},{"w":"sum","tr":"toplam / tutar / özetlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money or the total of several numbers","dt":"Para miktarı veya birkaç sayının toplamı","e1":"A large sum of money.","e1t":"Büyük bir para tutarı.","e2":"To sum up (to summarize).","e2t":"Özetlemek gerekirse."},{"w":"sunbathe","tr":"güneşlenmek","te":"Verb","tt":"Fiil","de":"To sit or lie in the sun to make your skin darker","dt":"Tenini koyulaştırmak için güneşte oturmak veya yatmak","e1":"We sunbathed on the beach all afternoon.","e1t":"Tüm öğleden sonra plajda güneşlendik.","e2":"I love to sunbathe during my holiday.","e2t":"Tatilim boyunca güneşlenmeyi severim."},{"w":"sunshine","tr":"gün ışığı / güneş parıltısı","te":"Noun","tt":"İsim","de":"The light and heat from the sun","dt":"Güneşten gelen ışık ve ısı","e1":"Let's go out and enjoy the sunshine.","e1t":"Hadi dışarı çıkalım ve gün ışığının tadını çıkaralım.","e2":"A ray of sunshine.","e2t":"Bir güneş ışığı (umut ışığı)."},{"w":"superficially","tr":"yüzeysel olarak / üstünkörü","te":"Adverb","tt":"Zarf","de":"In a superficial way","dt":"Yüzeysel bir biçimde","e1":"The problem was only superficially discussed.","e1t":"Sorun sadece yüzeysel olarak tartışıldı.","e2":"He resembles his father superficially.","e2t":"Babasına yüzeysel olarak (dış görünüşte) benziyor."},{"w":"superiority","tr":"üstünlük","te":"Noun","tt":"İsim","de":"The state of being superior","dt":"Üstün olma durumu","e1":"Air superiority.","e1t":"Hava üstünlüğü.","e2":"He has a sense of superiority.","e2t":"Kendini üstün görme (üstünlük) duygusu var."},{"w":"supermarket","tr":"süpermarket","te":"Noun","tt":"İsim","de":"A large shop that sells food and household goods","dt":"Yiyecek ve ev eşyaları satan büyük dükkan","e1":"I'm going to the supermarket to buy some groceries.","e1t":"Biraz bakkaliye almak için süpermarkete gidiyorum.","e2":"Supermarket prices.","e2t":"Süpermarket fiyatları."},{"w":"supervision","tr":"denetim / gözetim","te":"Noun","tt":"İsim","de":"The act of supervising","dt":"Denetleme veya gözetleme eylemi","e1":"Children should not be left without adult supervision.","e1t":"Çocuklar yetişkin gözetimi olmadan bırakılmamalıdır.","e2":"Under the supervision of a doctor.","e2t":"Bir doktorun denetimi altında."},{"w":"supper","tr":"akşam yemeği (genellikle hafif veya geç)","te":"Noun","tt":"İsim","de":"A light meal eaten in the evening","dt":"Akşam yemeği (hafif öğün)","e1":"What's for supper?","e1t":"Akşam yemeğinde ne var?","e2":"We had a late supper.","e2t":"Geç bir akşam yemeği yedik."},{"w":"supplier","tr":"tedarikçi","te":"Noun","tt":"İsim","de":"A person or company that provides goods or services","dt":"Mal veya hizmet sağlayan kişi veya şirket","e1":"They are our main suppliers of office equipment.","e1t":"Ofis ekipmanlarımızın ana tedarikçileridir.","e2":"Power supplier.","e2t":"Enerji tedarikçisi."},{"w":"supporter","tr":"destekçi / taraftar","te":"Noun","tt":"İsim","de":"A person who supports a team, idea, or person","dt":"Bir takımı, fikri veya kişiyi destekleyen kişi","e1":"He is a strong supporter of the new policy.","e1t":"Yeni politikanın güçlü bir destekçisidir.","e2":"Thousands of supporters gathered at the stadium.","e2t":"Binlerce taraftar stadyumda toplandı."},{"w":"supportive","tr":"destekleyici / yardımsever","te":"Adjective","tt":"Sıfat","de":"Giving help or encouragement","dt":"Yardım veya teşvik veren","e1":"My colleagues were very supportive during my illness.","e1t":"Hastalığım sırasında meslektaşlarım çok destekleyiciydi.","e2":"A supportive environment.","e2t":"Destekleyici bir ortam."},{"w":"supposedly","tr":"güya / sözde / varsayılanlara göre","te":"Adverb","tt":"Zarf","de":"According to what is generally believed","dt":"Genel inanışa veya söylenenlere göre","e1":"The novel is supposedly based on a true story.","e1t":"Romanın sözde (denilene göre) gerçek bir hikayeye dayandığı söyleniyor.","e2":"He is supposedly the best doctor in town.","e2t":"Güya kasabanın en iyi doktoru o."},{"w":"suppression","tr":"bastırma / durdurma / gizleme","te":"Noun","tt":"İsim","de":"The act of suppressing something","dt":"Bastırma veya engelleme eylemi","e1":"The suppression of free speech.","e1t":"İfade özgürlüğünün bastırılması.","e2":"Suppression of evidence.","e2t":"Delillerin gizlenmesi."},{"w":"supremacy","tr":"üstünlük / egemenlik","te":"Noun","tt":"İsim","de":"The state of being the highest in power or status","dt":"Güç veya statü bakımından en yüksek olma durumu","e1":"Air supremacy.","e1t":"Hava üstünlüğü.","e2":"The white supremacy (racism).","e2t":"Beyaz üstünlüğü (ırkçılık)."},{"w":"surely","tr":"kesinlikle / herhalde","te":"Adverb","tt":"Zarf","de":"Used to express surprise that something is not true","dt":"Bir şeyin doğru olmadığına şaşırmayı ifade etmek için kullanılır","e1":"Surely you're not going out in this rain!","e1t":"Herhalde bu yağmurda dışarı çıkmayacaksın!","e2":"Slowly but surely.","e2t":"Yavaş ama emin adımlarla."},{"w":"surf","tr":"sörf yapmak / internette gezinmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To ride on waves or to look at websites","dt":"Dalgaların üzerinde kaymak veya web sitelerine bakmak","e1":"I like to surf the internet in the evenings.","e1t":"Akşamları internette gezinmeyi severim.","e2":"He spent the summer surfing in Bali.","e2t":"Yazı Bali'de sörf yaparak geçirdi."},{"w":"surgical","tr":"cerrahi","te":"Adjective","tt":"Sıfat","de":"Relating to surgery","dt":"Ameliyat/cerrahi ile ilgili","e1":"Surgical instruments.","e1t":"Cerrahi aletler.","e2":"Surgical mask.","e2t":"Cerrahi maske."},{"w":"surprised","tr":"şaşırmış","te":"Adjective","tt":"Sıfat","de":"Feeling or showing surprise","dt":"Şaşkınlık hisseden veya gösteren","e1":"I was surprised to see him there.","e1t":"Onu orada gördüğüme şaşırdım.","e2":"You look surprised.","e2t":"Şaşırmış görünüyorsun."},{"w":"surprising","tr":"şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Causing surprise","dt":"Şaşkınlığa neden olan","e1":"It is surprising that no one noticed.","e1t":"Kimsenin fark etmemiş olması şaşırtıcı.","e2":"Surprising news.","e2t":"Şaşırtıcı haberler."},{"w":"surrounding","tr":"çevreleyen / etraftaki","te":"Adjective","tt":"Sıfat","de":"Everything that is around or near something","dt":"Bir şeyin etrafındaki veya yakınındaki her şey","e1":"Ankara and the surrounding areas.","e1t":"Ankara ve çevresindeki bölgeler.","e2":"Our surroundings (the environment).","e2t":"Çevremiz (etrafımız)."},{"w":"survivor","tr":"hayatta kalan / kazazede","te":"Noun","tt":"İsim","de":"A person who survives a dangerous event","dt":"Tehlikeli bir olaydan sağ kurtulan kişi","e1":"There were no survivors of the plane crash.","e1t":"Uçak kazasından sağ kurtulan olmadı.","e2":"He is a cancer survivor.","e2t":"O bir kanser savaşçısı (kanseri yenmiş kişi)."},{"w":"swap","tr":"takas etmek / değiş tokuş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give something and get something else in return","dt":"Bir şey verip karşılığında başka bir şey almak","e1":"Can we swap seats?","e1t":"Koltukları takas edebilir miyiz (yer değiştirelim mi)?","e2":"I did a swap with my friend.","e2t":"Arkadaşımla bir takas yaptım."},{"w":"swiftly","tr":"hızla / çabucak","te":"Adverb","tt":"Zarf","de":"Quickly","dt":"Hızlıca","e1":"The problem was dealt with swiftly.","e1t":"Sorunla çabucak ilgilenildi.","e2":"She moved swiftly through the crowd.","e2t":"Kalabalığın içinde hızla ilerledi."},{"w":"swimsuit","tr":"mayo","te":"Noun","tt":"İsim","de":"Clothing worn for swimming","dt":"Yüzmek için giyilen kıyafet","e1":"Don't forget to pack your swimsuit.","e1t":"Mayonu valize koymayı unutma.","e2":"A one","e2t":"piece swimsuit."},{"w":"symmetric","tr":"simetrik","te":"Adjective","tt":"Sıfat","de":"Having two halves that are exactly the same","dt":"Birbirinin tamamen aynısı olan iki yarıya sahip","e1":"The butterfly has symmetric wings.","e1t":"Kelebeğin simetrik kanatları vardır.","e2":"A symmetric pattern.","e2t":"Simetrik bir desen."},{"w":"systematically","tr":"sistematik olarak / düzenli bir şekilde","te":"Adverb","tt":"Zarf","de":"In a systematic way","dt":"Sistematik bir biçimde","e1":"The files were systematically archived.","e1t":"Dosyalar sistematik olarak arşivlendi.","e2":"He went through the list systematically.","e2t":"Listeyi sistematik bir şekilde gözden geçirdi."},{"w":"take off","tr":"havalanmak / çıkarmak (giysi) / başarılı olmak","te":"Verb","tt":"Fiil","de":"To leave the ground; to remove clothes","dt":"Yerden ayrılmak (uçak); kıyafet çıkarmak","e1":"The plane took off on time.","e1t":"Uçak zamanında havalandı.","e2":"Take off your coat.","e2t":"Paltonu çıkar."},{"w":"take over","tr":"devralmak / yönetimi ele almak","te":"Verb","tt":"Fiil","de":"To get control of something","dt":"Bir şeyin kontrolünü ele geçirmek","e1":"He took over the family business.","e1t":"Aile işini devraldı.","e2":"Robots are taking over the world!","e2t":"Robotlar dünyayı ele geçiriyor!"},{"w":"take up","tr":"başlamak (hobi/iş) / yer kaplamak","te":"Verb","tt":"Fiil","de":"To start a new activity; to fill space or time","dt":"Yeni bir faaliyete başlamak; yer veya zaman doldurmak","e1":"I’ve taken up scuba diving recently.","e1t":"Son zamanlarda tüplü dalışa başladım.","e2":"The new sofa takes up too much room.","e2t":"Yeni kanepe çok fazla yer kaplıyor."},{"w":"talented","tr":"yetenekli","te":"Adjective","tt":"Sıfat","de":"Having a natural ability to do something well","dt":"Bir şeyi iyi yapma konusunda doğal yeteneği olan","e1":"She is a very talented musician.","e1t":"O çok yetenekli bir müzisyendir.","e2":"Talented students.","e2t":"Yetenekli öğrenciler."},{"w":"tap","tr":"musluk / tıklatmak / hafifçe vurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device for controlling water; to hit lightly","dt":"Suyu kontrol eden cihaz; hafifçe vurmak","e1":"Turn off the tap.","e1t":"Musluğu kapat.","e2":"Tap the icon to open the app.","e2t":"Uygulamayı açmak için ikona tıkla (hafifçe vur)."},{"w":"tasty","tr":"lezzetli / tadı güzel","te":"Adjective","tt":"Sıfat","de":"Having a good flavor","dt":"Güzel bir lezzete sahip olan","e1":"This soup is very tasty.","e1t":"Bu çorba çok lezzetli.","e2":"A tasty meal.","e2t":"Tadı güzel bir yemek."},{"w":"teaching","tr":"öğretim / öğretmenlik / öğreti","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The job of being a teacher; or ideas taught","dt":"Öğretmenlik işi; veya öğretilen fikirler","e1":"She chose teaching as a career.","e1t":"Kariyer olarak öğretmenliği seçti.","e2":"The teachings of Socrates.","e2t":"Sokrates'in öğretileri."},{"w":"technically","tr":"teknik olarak","te":"Adverb","tt":"Zarf","de":"According to the facts or rules","dt":"Gerçeklere veya kurallara göre","e1":"Technically, you are right.","e1t":"Teknik olarak haklısın.","e2":"It is technically possible.","e2t":"Bu teknik olarak mümkün."},{"w":"technological","tr":"teknolojik","te":"Adjective","tt":"Sıfat","de":"Relating to technology","dt":"Teknoloji ile ilgili","e1":"Rapid technological change.","e1t":"Hızlı teknolojik değişim.","e2":"Technological developments.","e2t":"Teknolojik gelişmeler."},{"w":"teenage","tr":"gençlik / onlu yaşlar","te":"Adjective","tt":"Sıfat","de":"Relating to people between 13 and 19 years old","dt":"13 ile 19 yaş arasındaki insanlarla ilgili","e1":"Teenage rebellion.","e1t":"Gençlik isyanı.","e2":"Teenage daughter.","e2t":"Genç (ergen) kız evlat."},{"w":"telegram","tr":"telgraf","te":"Noun","tt":"İsim","de":"A message sent by telegraph and then printed","dt":"Telgrafla gönderilen ve sonra basılan mesaj","e1":"He received a telegram from his father.","e1t":"Babasından bir telgraf aldı.","e2":"Send a telegram.","e2t":"Telgraf çekmek."},{"w":"telegraph","tr":"telgraf (sistem) / telgraf çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A system for sending messages over a distance","dt":"Mesajları uzak mesafelere gönderme sistemi","e1":"The invention of the telegraph.","e1t":"Telgrafın icadı.","e2":"He telegraphed the news to the capital.","e2t":"Haberi başkente telgrafla bildirdi."},{"w":"termination","tr":"fesih / durdurma / sonlanma","te":"Noun","tt":"İsim","de":"The act of ending something","dt":"Bir şeyi bitirme eylemi","e1":"Termination of employment.","e1t":"İş akdinin feshi (işten çıkarma).","e2":"Early termination fee.","e2t":"Erken iptal (sonlandırma) ücreti."},{"w":"terribly","tr":"korkunç şekilde / çok / berbat bir biçimde","te":"Adverb","tt":"Zarf","de":"Very or in a terrible way","dt":"Çok veya korkunç bir şekilde","e1":"I am terribly sorry for being late.","e1t":"Geciktiğim için çok (korkunç derecede) üzgünüm.","e2":"He plays the guitar terribly.","e2t":"Gitarı berbat çalıyor."},{"w":"textbook","tr":"ders kitabı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A book used for the study of a subject","dt":"Bir konunun çalışılması için kullanılan kitap","e1":"I need to buy a physics textbook.","e1t":"Bir fizik ders kitabı almam gerekiyor.","e2":"A textbook example of the disease.","e2t":"Hastalığın ders kitaplık (tipik) bir örneği."},{"w":"thanks to","tr":"sayesinde /","te":"den dolayı","tt":"Preposition","de":"Edat","dt":"Because of someone or something","e1":"Birisi veya bir şey sayesinde","e1t":"Thanks to your help, I finished the project.","e2":"Senin yardımın sayesinde projeyi bitirdim.","e2t":"Thanks to modern technology..."},{"w":"theoretically","tr":"teorik olarak","te":"Adverb","tt":"Zarf","de":"In a theoretical way","dt":"Teorik bir biçimde","e1":"Theoretically, it should work.","e1t":"Teorik olarak çalışması gerekir.","e2":"It is theoretically possible but difficult.","e2t":"Teorik olarak mümkün ama zor."},{"w":"therapy","tr":"terapi / tedavi","te":"Noun","tt":"İsim","de":"Treatment to help someone feel better","dt":"Birinin daha iyi hissetmesini sağlayan tedavi","e1":"Group therapy.","e1t":"Grup terapisi.","e2":"He is undergoing occupational therapy.","e2t":"İş (uğraşı) terapisi görüyor."},{"w":"therefore","tr":"bu yüzden / dolayısıyla","te":"Adverb","tt":"Zarf","de":"For that reason","dt":"O sebeple","e1":"He was ill, therefore he couldn't come.","e1t":"Hastaydı, bu yüzden gelemedi.","e2":"I think, therefore I am.","e2t":"Düşünüyorum, öyleyse varım."},{"w":"thicken","tr":"kalınlaştırmak / koyulaştırmak","te":"Verb","tt":"Fiil","de":"To make or become thick","dt":"Kalınlaşmak veya koyulaştırmak","e1":"Use flour to thicken the sauce.","e1t":"Sosu koyulaştırmak için un kullanın.","e2":"The plot thickens (becomes more complex).","e2t":"Olaylar karmaşıklaşıyor (düğüm noktasına geliyor)."},{"w":"thickness","tr":"kalınlık / yoğunluk","te":"Noun","tt":"İsim","de":"The quality of being thick","dt":"Kalın olma özelliği","e1":"The thickness of the walls.","e1t":"Duvarların kalınlığı.","e2":"Check the thickness of the oil.","e2t":"Yağın yoğunluğunu kontrol et."},{"w":"thief","tr":"hırsız","te":"Noun","tt":"İsim","de":"A person who steals","dt":"Çalan kişi","e1":"The thief stole my wallet.","e1t":"Hırsız cüzdanımı çaldı.","e2":"Stop! Thief!","e2t":"Dur! Hırsız!"},{"w":"think over","tr":"iyice düşünmek / üzerinde kafa yormak","te":"Verb","tt":"Fiil","de":"To consider something carefully","dt":"Bir şeyi dikkatle düşünmek","e1":"I need some time to think over your offer.","e1t":"Teklifini iyice düşünmek için biraz zamana ihtiyacım var.","e2":"Think it over before you decide.","e2t":"Karar vermeden önce üzerinde kafa yor."},{"w":"thirst","tr":"susuzluk / arzu","te":"Noun/Verb","tt":"İsim/Fiil","de":"The feeling of needing to drink","dt":"İçme ihtiyacı hissi","e1":"I need a drink to satisfy my thirst.","e1t":"Susuzluğumu gidermek için bir içeceğe ihtiyacım var.","e2":"A thirst for knowledge.","e2t":"Bilgiye duyulan arzu (açlık)."},{"w":"thorn","tr":"diken","te":"Noun","tt":"İsim","de":"A small sharp point on a plant","dt":"Bitki üzerindeki küçük keskin nokta","e1":"Every rose has its thorn.","e1t":"Her gülün dikeni vardır.","e2":"I pricked my finger on a thorn.","e2t":"Parmağıma bir diken battı."},{"w":"thoroughly","tr":"tamamen / titizlikle / iyice","te":"Adverb","tt":"Zarf","de":"Completely or very carefully","dt":"Tamamen veya çok dikkatlice","e1":"I am thoroughly confused.","e1t":"Tamamen kafam karıştı.","e2":"Clean the room thoroughly.","e2t":"Odayı titizlikle (iyice) temizle."},{"w":"thoughtless","tr":"düşüncesiz / bencilce","te":"Adjective","tt":"Sıfat","de":"Not thinking about the needs of others","dt":"Başkalarının ihtiyaçlarını düşünmeyen","e1":"It was a thoughtless remark.","e1t":"Düşüncesizce bir sözdü.","e2":"Stop being so thoughtless!","e2t":"Bu kadar düşüncesiz olmayı bırak!"},{"w":"threatening","tr":"tehditkar / korkutucu","te":"Adjective","tt":"Sıfat","de":"Expressing a threat","dt":"Tehdit ifade eden","e1":"He gave me a threatening look.","e1t":"Bana tehditkar bir bakış attı.","e2":"Threatening letters.","e2t":"Tehdit mektupları."},{"w":"tight","tr":"sıkı / dar","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not loose; fitting closely to the body","dt":"Gevşek olmayan; vücuda tam oturan","e1":"These shoes are too tight.","e1t":"Bu ayakkabılar çok dar.","e2":"Hold on tight!","e2t":"Sıkı tutun!"},{"w":"tighten","tr":"sıkılaştırmak / germek","te":"Verb","tt":"Fiil","de":"To make something tighter","dt":"Bir şeyi daha sıkı hale getirmek","e1":"You should tighten the screws.","e1t":"Vidaları sıkılaştırmalısın.","e2":"The security has been tightened.","e2t":"Güvenlik önlemleri artırıldı (sıkılaştırıldı)."},{"w":"timely","tr":"zamanında / tam vaktinde","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Happening at the right time","dt":"Doğru zamanda gerçekleşen","e1":"Thank you for your timely intervention.","e1t":"Zamanında müdahaleniz için teşekkür ederim.","e2":"A timely reminder.","e2t":"Tam vaktinde gelen bir hatırlatma."},{"w":"timetable","tr":"ders programı / zaman çizelgesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A list of times when things are planned to happen","dt":"Şeylerin planlandığı zamanların listesi","e1":"Let's check the train timetable.","e1t":"Tren saatlerine (zaman çizelgesine) bakalım.","e2":"School timetable.","e2t":"Okul ders programı."},{"w":"tire","tr":"yormak / bıkmak / lastik (tyre)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make someone feel in need of rest","dt":"Birini dinlenme ihtiyacı içinde hissettirmek","e1":"The long walk tired the children.","e1t":"Uzun yürüyüş çocukları yordu.","e2":"I never tire of this song.","e2t":"Bu şarkıdan hiç bıkmam."},{"w":"tiresome","tr":"yorucu / can sıkıcı / bıktırıcı","te":"Adjective","tt":"Sıfat","de":"Boring or annoying","dt":"Sıkıcı veya sinir bozucu","e1":"It was a tiresome journey.","e1t":"Yorucu (sıkıcı) bir yolculuktu.","e2":"A tiresome task.","e2t":"Bıktırıcı bir görev."},{"w":"tomb","tr":"mezar / türbe","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where a dead person is buried","dt":"Ölü birinin gömüldüğü yer","e1":"The Pharaoh's tomb.","e1t":"Firavun'un mezarı.","e2":"Unknown Soldier's Tomb.","e2t":"Meçhul Asker Anıtı."},{"w":"ton","tr":"ton (1000 kg) / çok fazla","te":"Noun","tt":"İsim","de":"A unit of weight equal to 1,000 kilograms","dt":"1.000 kilograma eşit ağırlık birimi","e1":"The truck carries 10 tons of coal.","e1t":"Kamyon 10 ton kömür taşıyor.","e2":"I have tons of work to do.","e2t":"Yapacak tonla (çok fazla) işim var."},{"w":"totally","tr":"tamamen / bütünüyle","te":"Adverb","tt":"Zarf","de":"Completely","dt":"Bütünüyle","e1":"I totally agree with you.","e1t":"Sana tamamen katılıyorum.","e2":"The car was totally destroyed.","e2t":"Araba tamamen mahvoldu."},{"w":"touching","tr":"dokunaklı / etkileyici","te":"Adjective","tt":"Sıfat","de":"Causing feelings of sadness or sympathy","dt":"Üzüntü veya sempati duygularına neden olan","e1":"It was a very touching story.","e1t":"Çok dokunaklı bir hikayeydi.","e2":"A touching moment.","e2t":"Etkileyici bir an."},{"w":"tourism","tr":"turizm","te":"Noun","tt":"İsim","de":"The business of providing services for people on holiday","dt":"Tatildeki insanlar için hizmet sağlama işi","e1":"Tourism is a major industry in Turkey.","e1t":"Turizm, Türkiye'de büyük bir endüstridir.","e2":"Eco","e2t":"tourism."},{"w":"toward / towards","tr":"","te":"e doğru / karşı","tt":"Preposition","de":"Edat","dt":"In the direction of or relating to","e1":"Bir yöne doğru veya bir şeye karşı","e1t":"He walked towards the door.","e2":"Kapıya doğru yürüdü.","e2t":"Our attitude towards work."},{"w":"toxin","tr":"toksin / zehir","te":"Noun","tt":"İsim","de":"A poisonous substance produced by a living thing","dt":"Canlı bir varlık tarafından üretilen zehirli madde","e1":"The bacteria produce a dangerous toxin.","e1t":"Bakteriler tehlikeli bir toksin üretir.","e2":"Eliminate toxins from your body.","e2t":"Vücudundaki toksinleri at."},{"w":"toy","tr":"oyuncak","te":"Noun/Verb/Adj","tt":"An object for children to play with","de":"Çocukların oynaması için nesne","dt":"He is playing with his toy cars.","e1":"Oyuncak arabalarıyla oynuyor.","e1t":"Toy shop.","e2":"Oyuncak dükkanı.","e2t":""},{"w":"tractor","tr":"traktör","te":"Noun","tt":"İsim","de":"A powerful vehicle used on farms","dt":"Çiftliklerde kullanılan güçlü araç","e1":"The farmer is driving a tractor.","e1t":"Çiftçi traktör sürüyor.","e2":"Tractor parts.","e2t":"Traktör parçaları."},{"w":"trade","tr":"ticaret / takas / ticaret yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The activity of buying and selling","dt":"Alım satım faaliyeti","e1":"International trade.","e1t":"Uluslararası ticaret.","e2":"We traded our old car for a new one.","e2t":"Eski arabamızı yenisiyle takas ettik."},{"w":"traditionally","tr":"geleneksel olarak","te":"Adverb","tt":"Zarf","de":"According to tradition","dt":"Geleneğe göre","e1":"Traditionally, weddings lasted for three days.","e1t":"Geleneksel olarak düğünler üç gün sürerdi.","e2":"This dish is traditionally served with rice.","e2t":"Bu yemek geleneksel olarak pirinçle servis edilir."},{"w":"traffic","tr":"trafik / trafik akışı","te":"Noun/Verb","tt":"İsim/Fiil","de":"The number of vehicles or people moving on a road","dt":"Yolda hareket eden araç veya insan sayısı","e1":"There is a lot of traffic today.","e1t":"Bugün çok trafik var.","e2":"Traffic jam.","e2t":"Trafik sıkışıklığı."},{"w":"tragic","tr":"trajik / feci / üzücü","te":"Adjective","tt":"Sıfat","de":"Very sad or relating to tragedy","dt":"Çok üzücü veya trajediyle ilgili","e1":"A tragic accident.","e1t":"Trajik bir kaza.","e2":"It was a tragic loss.","e2t":"Üzücü (feci) bir kayıptı."},{"w":"trainee","tr":"stajyer / eğitim gören","te":"Noun","tt":"İsim","de":"A person who is being trained for a job","dt":"Bir iş için eğitim alan kişi","e1":"He is a trainee manager.","e1t":"O bir yönetici stajyeridir.","e2":"Teacher trainee.","e2t":"Stajyer öğretmen."},{"w":"transcription","tr":"transkripsiyon / yazıya dökme","te":"Noun","tt":"İsim","de":"The act of transcribing","dt":"Yazıya dökme eylemi","e1":"Phonetic transcription.","e1t":"Fonetik transkripsiyon.","e2":"A transcription of the speech.","e2t":"Konuşmanın yazıya dökülmüş hali."},{"w":"transitional","tr":"geçiş süreciyle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to a transition","dt":"Geçişle ilgili","e1":"A transitional government.","e1t":"Geçiş hükümeti.","e2":"Transitional period.","e2t":"Geçiş dönemi."},{"w":"transmitter","tr":"verici / iletici","te":"Noun","tt":"İsim","de":"A device that sends out radio or TV signals","dt":"Radyo veya TV sinyalleri gönderen cihaz","e1":"Radio transmitter.","e1t":"Radyo vericisi.","e2":"A wireless transmitter.","e2t":"Kablosuz verici."},{"w":"transparency","tr":"şeffaflık / saydamlık","te":"Noun","tt":"İsim","de":"The quality of being easy to see through or honest","dt":"İçinden görülme kolaylığı veya dürüstlük","e1":"We need more transparency in government.","e1t":"Hükümette daha fazla şeffaflığa ihtiyacımız var.","e2":"The transparency of the water.","e2t":"Suyun berraklığı (saydamlığı)."},{"w":"traumatic","tr":"travmatik / sarsıcı","te":"Adjective","tt":"Sıfat","de":"Causing severe emotional shock","dt":"Şiddetli duygusal şoka neden olan","e1":"It was a traumatic experience for everyone.","e1t":"Herkes için travmatik bir deneyimdi.","e2":"Traumatic memories.","e2t":"Sarsıcı (travmatik) anılar."},{"w":"traveler / traveller","tr":"gezgin / yolcu","te":"Noun","tt":"İsim","de":"A person who travels","dt":"Seyahat eden kişi","e1":"He is a frequent traveler.","e1t":"O sık seyahat eden biridir.","e2":"Tips for international travelers.","e2t":"Uluslararası yolcular için ipuçları."},{"w":"treacherous","tr":"haince / tehlikeli / güvenilmez","te":"Adjective","tt":"Sıfat","de":"Not able to be trusted; or very dangerous","dt":"Güvenilemez; veya çok tehlikeli","e1":"The roads were treacherous due to the ice.","e1t":"Buzlanma nedeniyle yollar çok tehlikeliydi.","e2":"A treacherous person.","e2t":"Hain (güvenilmez) bir kişi."},{"w":"treasurer","tr":"sayman / veznedar","te":"Noun","tt":"İsim","de":"A person in charge of the money of an organization","dt":"Bir kuruluşun parasından sorumlu olan kişi","e1":"He was elected as the club treasurer.","e1t":"Kulüp saymanı olarak seçildi.","e2":"The treasurer's report.","e2t":"Sayman raporu."},{"w":"tree","tr":"ağaç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tall plant with a wooden trunk and branches","dt":"Odunsu gövdesi ve dalları olan uzun bitki","e1":"We planted an olive tree in the garden.","e1t":"Bahçeye bir zeytin ağacı diktik.","e2":"Fruit trees.","e2t":"Meyve ağaçları."},{"w":"trespass","tr":"izinsiz girmek (mülke) / ihlal etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go onto someone's land without permission","dt":"Birinin arazisine izinsiz girmek","e1":"No trespassing!","e1t":"İzinsiz girmek yasaktır!","e2":"He was arrested for trespassing.","e2t":"Mülke tecavüzden (izinsiz girişten) tutuklandı."},{"w":"tribal","tr":"kabileye ait / aşiret ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to a tribe","dt":"Bir kabileyle ilgili","e1":"Tribal customs.","e1t":"Kabile gelenekleri.","e2":"Tribal warfare.","e2t":"Kabileler arası savaş."},{"w":"tricky","tr":"zor / hileli / kurnazlık gerektiren","te":"Adjective","tt":"Sıfat","de":"Difficult to deal with or do","dt":"Başa çıkması veya yapması zor","e1":"This is a tricky question.","e1t":"Bu çetrefilli (zor) bir soru.","e2":"A tricky situation.","e2t":"Zor (hassas) bir durum."},{"w":"trifle","tr":"önemsiz şey / cüzi miktar","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something of little importance","dt":"Az önemi olan şey","e1":"We shouldn't argue over trifles.","e1t":"Önemsiz şeyler için tartışmamalıyız.","e2":"A trifle expensive.","e2t":"Birazcık (bir nebze) pahalı."},{"w":"trout","tr":"alabalık","te":"Noun","tt":"İsim","de":"A common freshwater fish","dt":"Yaygın bir tatlı su balığı","e1":"We caught some trout in the river.","e1t":"Nehirde biraz alabalık yakaladık.","e2":"Grilled trout.","e2t":"Izgara alabalık."},{"w":"truly","tr":"gerçekten / içtenlikle","te":"Adverb","tt":"Zarf","de":"Sincerely or completely","dt":"İçtenlikle veya tamamen","e1":"I am truly sorry.","e1t":"Gerçekten üzgünüm.","e2":"A truly remarkable achievement.","e2t":"Gerçekten dikkat çekici bir başarı."},{"w":"try out","tr":"denemek / test etmek","te":"Verb","tt":"Fiil","de":"To test something to see if it works or if you like it","dt":"Bir şeyin çalışıp çalışmadığını veya sevip sevmediğini görmek için test etmek","e1":"I'm going to try out the new software.","e1t":"Yeni yazılımı deneyeceğim (test edeceğim).","e2":"He is trying out for the football team.","e2t":"Futbol takımı için seçmelere giriyor (kendini deniyor)."},{"w":"tube","tr":"tüp / boru / metro (Londra)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long hollow cylinder; or the London subway","dt":"Uzun içi boş silindir; veya Londra metrosu","e1":"A tube of toothpaste.","e1t":"Bir tüp diş macunu.","e2":"I take the Tube to work.","e2t":"İşe metroyla (Londra) giderim."},{"w":"turn down","tr":"reddetmek / (sesini) kısmak","te":"Verb","tt":"Fiil","de":"To refuse an offer; to reduce the level of sound","dt":"Bir teklifi reddetmek; ses seviyesini azaltmak","e1":"He turned down the job offer.","e1t":"İş teklifini reddetti.","e2":"Please turn down the music.","e2t":"Lütfen müziğin sesini kıs."},{"w":"turn into","tr":"dönüşmek /","te":"e dönüşmek","tt":"Verb","de":"Fiil","dt":"To become something different","e1":"Farklı bir şeye dönüşmek","e1t":"The ice turned into water.","e2":"Buz suya dönüştü.","e2t":"The small business turned into a large company."},{"w":"turn off","tr":"kapatmak (ışık, cihaz vb.)","te":"Verb","tt":"Fiil","de":"To stop a machine or a light from working","dt":"Bir makineyi veya ışığı durdurmak","e1":"Don't forget to turn off the lights.","e1t":"Işıkları kapatmayı unutma.","e2":"Turn off the oven.","e2t":"Fırını kapat."},{"w":"turn on","tr":"açmak (ışık, cihaz vb.)","te":"Verb","tt":"Fiil","de":"To start a machine or a light working","dt":"Bir makineyi veya ışığı çalıştırmak","e1":"Can you turn on the TV?","e1t":"Televizyonu açabilir miyiz?","e2":"She turned on the heater.","e2t":"Isıtıcıyı açtı."},{"w":"turn out","tr":"sonuçlanmak / ortaya çıkmak / katılım sağlamak","te":"Verb","tt":"Fiil","de":"To happen in a particular way; to be discovered","dt":"Belirli bir şekilde gerçekleşmek; keşfedilmek","e1":"It turned out that he was lying.","e1t":"Onun yalan söylediği ortaya çıktı.","e2":"How did the cake turn out?","e2t":"Kek nasıl oldu (sonuçlandı)?"},{"w":"turn over","tr":"çevirmek / ciro yapmak / devretmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn to the other side; the amount of business done","dt":"Diğer tarafa çevirmek; yapılan iş miktarı (ciro)","e1":"Turn over the page.","e1t":"Sayfayı çevir.","e2":"The company has an annual turnover of £1 million.","e2t":"Şirketin yıllık 1 milyon sterlin cirosu var."},{"w":"turn up","tr":"sesini açmak / çıkagelmek / ortaya çıkmak","te":"Verb","tt":"Fiil","de":"To increase the volume; to arrive","dt":"Sesi artırmak; varmak (gelmek)","e1":"Turn up the radio!","e1t":"Radyonun sesini aç!","e2":"He turned up late for the meeting.","e2t":"Toplantıya geç geldi."},{"w":"turtle","tr":"kaplumbağa (deniz)","te":"Noun","tt":"İsim","de":"A sea animal with a hard shell","dt":"Sert kabuklu deniz hayvanı","e1":"Sea turtles lay their eggs on the beach.","e1t":"Deniz kaplumbağaları yumurtalarını plaja bırakır.","e2":"Green turtle.","e2t":"Yeşil kaplumbağa."},{"w":"tutorial","tr":"öğretici / özel ders","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A period of study with a tutor or an online guide","dt":"Bir eğitmenle yapılan çalışma veya çevrimiçi rehber","e1":"I watched a video tutorial on how to use the software.","e1t":"Yazılımın nasıl kullanılacağına dair bir video eğitim (öğretici) izledim.","e2":"Online tutorials.","e2t":"Çevrimiçi öğreticiler."},{"w":"twig","tr":"dal / ince dal","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very small thin branch from a tree","dt":"Ağaçtan gelen çok küçük ince dal","e1":"The bird was carrying a small twig.","e1t":"Kuş küçük bir ince dal taşıyordu.","e2":"Dry twigs.","e2t":"Kuru dallar."},{"w":"typewriter","tr":"daktilo","te":"Noun","tt":"İsim","de":"A machine with keys for printing words on paper","dt":"Kağıda kelime basmak için tuşları olan makine","e1":"My grandfather used an old typewriter.","e1t":"Dedem eski bir daktilo kullanırdı.","e2":"The sound of a typewriter.","e2t":"Daktilo sesi."},{"w":"typically","tr":"tipik olarak / genellikle","te":"Adverb","tt":"Zarf","de":"In a way that is usual for a person or thing","dt":"Bir kişi veya şey için alışılmış olan şekilde","e1":"Typically, the weather is hot in July.","e1t":"Tipik olarak (genellikle) Temmuz ayında hava sıcaktır.","e2":"He was typically late.","e2t":"Her zamanki gibi (tipik bir şekilde) geç kaldı."},{"w":"typography","tr":"tipografi / yazı karakteri sanatı","te":"Noun","tt":"İsim","de":"The design and appearance of printed letters","dt":"Basılı harflerin tasarımı ve görünümü","e1":"I love the typography in this book.","e1t":"Bu kitaptaki tipografiyi seviyorum.","e2":"Web typography.","e2t":"Web tipografisi."},{"w":"tyranny","tr":"zorbalık / tiranlık / zulüm","te":"Noun","tt":"İsim","de":"A government that is cruel and unfair","dt":"Zalim ve adaletsiz hükümet","e1":"They fought against tyranny.","e1t":"Zorbalığa karşı savaştılar.","e2":"The tyranny of the majority.","e2t":"Çoğunluğun tahakkümü (zorbalığı)."},{"w":"unacceptable","tr":"kabul edilemez","te":"Adjective","tt":"Sıfat","de":"Not allowed or approved of","dt":"İzin verilmeyen veya onaylanmayan","e1":"Such behavior is completely unacceptable.","e1t":"Bu tür bir davranış tamamen kabul edilemez.","e2":"Unacceptable conditions.","e2t":"Kabul edilemez koşullar."},{"w":"unarmed","tr":"silahsız","te":"Adjective","tt":"Sıfat","de":"Not carrying any weapons","dt":"Hiçbir silah taşımayan","e1":"The police shot an unarmed man.","e1t":"Polis silahsız bir adamı vurdu.","e2":"Unarmed combat.","e2t":"Silahsız dövüş."},{"w":"unavoidable","tr":"kaçınılmaz","te":"Adjective","tt":"Sıfat","de":"Impossible to avoid or prevent","dt":"Kaçınılması veya önlenmesi imkansız","e1":"Accidents are sometimes unavoidable.","e1t":"Kazalar bazen kaçınılmazdır.","e2":"An unavoidable delay.","e2t":"Kaçınılmaz bir gecikme."},{"w":"unaware","tr":"habersiz / farkında olmayan","te":"Adjective","tt":"Sıfat","de":"Not knowing about something","dt":"Bir şey hakkında bilgi sahibi olmama","e1":"He was unaware of the danger.","e1t":"Tehlikenin farkında değildi.","e2":"I was unaware that you were coming.","e2t":"Geleceğinden habersizdim."},{"w":"unbearable","tr":"dayanılmaz / çekilmez","te":"Adjective","tt":"Sıfat","de":"Too unpleasant or painful to deal with","dt":"Başa çıkılamayacak kadar nahoş veya acı verici","e1":"The heat was unbearable.","e1t":"Sıcaklık dayanılmazdı.","e2":"Unbearable pain.","e2t":"Dayanılmaz acı."},{"w":"unbelievable","tr":"inanılmaz","te":"Adjective","tt":"Sıfat","de":"Extremely surprising or difficult to believe","dt":"Son derece şaşırtıcı veya inanması güç","e1":"It’s an unbelievable story.","e1t":"Bu inanılmaz bir hikaye.","e2":"Unbelievable prices.","e2t":"İnanılmaz fiyatlar."},{"w":"uncle","tr":"amca / dayı","te":"Noun","tt":"İsim","de":"The brother of your father or mother","dt":"Babanızın veya annenizin erkek kardeşi","e1":"My uncle lives in Germany.","e1t":"Amcam (veya dayım) Almanya'da yaşıyor.","e2":"Great","e2t":"uncle."},{"w":"understandable","tr":"anlaşılabilir","te":"Adjective","tt":"Sıfat","de":"Easy to understand or natural","dt":"Anlaması kolay veya doğal","e1":"Her anger is understandable.","e1t":"Onun öfkesi anlaşılabilir.","e2":"For understandable reasons.","e2t":"Anlaşılabilir nedenlerden dolayı."},{"w":"understanding","tr":"anlayış / kavrayış / anlaşma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Knowledge or a formal agreement","dt":"Bilgi (anlayış) veya resmi bir anlaşma","e1":"He has a clear understanding of the situation.","e1t":"Durumu net bir şekilde kavrıyor.","e2":"We reached a mutual understanding.","e2t":"Karşılıklı bir anlayışa (anlaşmaya) vardık."},{"w":"undesirable","tr":"istenmeyen / hoşa gitmeyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not wanted or not liked","dt":"İstenmeyen veya sevilmeyen","e1":"Undesirable side effects.","e1t":"İstenmeyen yan etkiler.","e2":"These people are socially undesirable.","e2t":"Bu insanlar sosyal açıdan istenmeyen kişilerdir."},{"w":"undoubtedly","tr":"şüphesiz / kuşkusuz","te":"Adverb","tt":"Zarf","de":"Without any doubt","dt":"Hiç şüphesiz","e1":"Undoubtedly, it was the best decision.","e1t":"Kuşkusuz, bu en iyi karardı.","e2":"He is undoubtedly talented.","e2t":"O şüphesiz yetenekli biri."},{"w":"undress","tr":"soyunmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take off your clothes","dt":"Kıyafetlerini çıkarmak","e1":"She undressed and got into bed.","e1t":"Soyundu ve yatağa girdi.","e2":"He undressed the baby.","e2t":"Bebeği soydu."},{"w":"unemployed","tr":"işsiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Without a job","dt":"İşi olmayan","e1":"He has been unemployed for six months.","e1t":"Altı aydır işsiz.","e2":"The number of unemployed is rising.","e2t":"İşsizlerin sayısı artıyor."},{"w":"unexpectedly","tr":"beklenmedik bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that was not expected","dt":"Beklenmeyen bir biçimde","e1":"He died unexpectedly.","e1t":"Beklenmedik bir şekilde öldü.","e2":"The weather changed unexpectedly.","e2t":"Hava beklenmedik bir şekilde değişti."},{"w":"unfortunate","tr":"talihsiz / şanssız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unlucky or regrettable","dt":"Şanssız veya üzücü","e1":"An unfortunate accident.","e1t":"Talihsiz bir kaza.","e2":"It was an unfortunate choice of words.","e2t":"Talihsiz bir kelime seçimiydi."},{"w":"unhealthy","tr":"sağlıksız","te":"Adjective","tt":"Sıfat","de":"Not having good health or harmful to health","dt":"Sağlığı iyi olmayan veya sağlığa zararlı","e1":"An unhealthy lifestyle.","e1t":"Sağlıksız bir yaşam tarzı.","e2":"Unhealthy snacks.","e2t":"Sağlıksız atıştırmalıklar."},{"w":"uniquely","tr":"benzersiz bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that is unique","dt":"Benzersiz bir biçimde","e1":"He is uniquely qualified for the job.","e1t":"Bu iş için benzersiz bir yeterliliğe sahip.","e2":"A uniquely designed building.","e2t":"Benzersiz şekilde tasarlanmış bir bina."},{"w":"universally","tr":"evrensel olarak / her yerde","te":"Adverb","tt":"Zarf","de":"By everyone or in every case","dt":"Herkes tarafından veya her durumda","e1":"The film was universally acclaimed.","e1t":"Film evrensel olarak (herkesçe) beğenildi.","e2":"A universally accepted truth.","e2t":"Evrensel olarak kabul görmüş bir gerçek."},{"w":"unjust","tr":"adaletsiz / haksız","te":"Adjective","tt":"Sıfat","de":"Not fair or reasonable","dt":"Adil veya mantıklı olmayan","e1":"An unjust law.","e1t":"Adaletsiz bir yasa.","e2":"It was an unjust accusation.","e2t":"Bu haksız bir suçlamaydı."},{"w":"unlike","tr":"aksine /","te":"in aksine / benzemeyen","tt":"Preposition/Adj","de":"Different from someone or something","dt":"Birinden veya bir şeyden farklı olarak","e1":"Unlike his brother, he is very shy.","e1t":"Kardeşinin aksine, o çok utangaçtır.","e2":"The two projects are quite unlike.","e2t":"İki proje birbirinden oldukça farklı."},{"w":"unlimited","tr":"sınırsız","te":"Adjective","tt":"Sıfat","de":"Without any limit or end","dt":"Herhangi bir sınır veya son olmaksızın","e1":"Unlimited internet access.","e1t":"Sınırsız internet erişimi.","e2":"The possibilities are unlimited.","e2t":"Olasılıklar sınırsızdır."},{"w":"unlock","tr":"kilidini açmak / çözmek","te":"Verb","tt":"Fiil","de":"To open a lock using a key; or to access","dt":"Anahtar kullanarak kilit açmak; veya erişmek","e1":"I can't unlock the door.","e1t":"Kapının kilidini açamıyorum.","e2":"To unlock your full potential.","e2t":"Tam potansiyelini açığa çıkarmak (çözmek)."},{"w":"unlucky","tr":"şanssız / uğursuz","te":"Adjective","tt":"Sıfat","de":"Not having good luck","dt":"İyi şansı olmayan","e1":"He was unlucky to lose the match.","e1t":"Maçı kaybettiği için şanssızdı.","e2":"Some people think thirteen is an unlucky number.","e2t":"Bazı insanlar on üçün uğursuz bir sayı olduğunu düşünür."},{"w":"unnecessary","tr":"gereksiz","te":"Adjective","tt":"Sıfat","de":"Not needed","dt":"İhtiyaç duyulmayan","e1":"Avoid unnecessary risks.","e1t":"Gereksiz risklerden kaçının.","e2":"It was an unnecessary comment.","e2t":"Gereksiz bir yorumdu."},{"w":"unpleasant","tr":"nahoş / tatsız","te":"Adjective","tt":"Sıfat","de":"Not enjoyable or nice","dt":"Keyifli veya güzel olmayan","e1":"An unpleasant smell.","e1t":"Nahoş bir koku.","e2":"We had an unpleasant experience.","e2t":"Tatsız bir tecrübe yaşadık."},{"w":"unpredictable","tr":"öngörülemez / ne yapacağı belli olmayan","te":"Adjective","tt":"Sıfat","de":"Not able to be foreseen or known beforehand","dt":"Önceden görülemeyen veya bilinemeyen","e1":"The weather here is very unpredictable.","e1t":"Burada hava durumu çok öngörülemez.","e2":"He is a brilliant but unpredictable player.","e2t":"O zeki ama ne yapacağı belli olmayan bir oyuncu."},{"w":"unqualified","tr":"niteliksiz / vasıfsız / kayıtsız şartsız","te":"Adjective","tt":"Sıfat","de":"Not having the necessary skills or conditions","dt":"Gerekli becerilere veya şartlara sahip olmayan","e1":"He is unqualified for the job.","e1t":"O iş için vasıfsız (yetersiz).","e2":"Unqualified support.","e2t":"Kayıtsız şartsız destek."},{"w":"unreasonable","tr":"mantıksız / makul olmayan","te":"Adjective","tt":"Sıfat","de":"Not fair or sensible","dt":"Adil veya mantıklı olmayan","e1":"An unreasonable request.","e1t":"Makul olmayan bir talep.","e2":"He has an unreasonable fear of dogs.","e2t":"Mantıksız bir köpek korkusu var."},{"w":"unreliable","tr":"güvenilmez","te":"Adjective","tt":"Sıfat","de":"Not able to be trusted or depended on","dt":"Güvenilemeyen veya bel bağlanamayan","e1":"An unreliable car.","e1t":"Güvenilmez (sürekli bozulan) bir araba.","e2":"He is an unreliable witness.","e2t":"O güvenilmez bir tanık."},{"w":"unsatisfactory","tr":"tatmin edici olmayan / yetersiz","te":"Adjective","tt":"Sıfat","de":"Not good enough","dt":"Yeterince iyi olmayan","e1":"The exam results were unsatisfactory.","e1t":"Sınav sonuçları tatmin edici değildi.","e2":"An unsatisfactory explanation.","e2t":"Yetersiz bir açıklama."},{"w":"unskilled","tr":"vasıfsız / beceri gerektirmeyen","te":"Adjective","tt":"Sıfat","de":"Not having special skills or training","dt":"Özel beceri veya eğitim gerektirmeyen","e1":"Unskilled labor.","e1t":"Vasıfsız iş gücü.","e2":"An unskilled worker.","e2t":"Vasıfsız bir işçi."},{"w":"unsuccessful","tr":"başarısız","te":"Adjective","tt":"Sıfat","de":"Not achieving what was wanted","dt":"İstenileni başaramayan","e1":"An unsuccessful attempt.","e1t":"Başarısız bir girişim.","e2":"He was unsuccessful in his job hunt.","e2t":"İş arayışında başarısız oldu."},{"w":"unsuitable","tr":"uygunsuz / elverişsiz","te":"Adjective","tt":"Sıfat","de":"Not right or appropriate","dt":"Doğru veya uygun olmayan","e1":"This film is unsuitable for young children.","e1t":"Bu film küçük çocuklar için uygun değildir.","e2":"Unsuitable clothes for the weather.","e2t":"Hava için elverişsiz kıyafetler."},{"w":"unusually","tr":"alışılmadık şekilde / sıra dışı bir biçimde","te":"Adverb","tt":"Zarf","de":"In a way that is not common","dt":"Yaygın olmayan bir biçimde","e1":"The weather is unusually warm for October.","e1t":"Hava, Ekim ayı için alışılmadık derecede sıcak.","e2":"An unusually large crowd.","e2t":"Sıra dışı büyüklükte bir kalabalık."},{"w":"unwilling","tr":"isteksiz","te":"Adjective","tt":"Sıfat","de":"Not wanting to do something","dt":"Bir şeyi yapmayı istemeyen","e1":"He was unwilling to help.","e1t":"Yardım etmeye isteksizdi.","e2":"An unwilling participant.","e2t":"Gönülsüz (isteksiz) katılımcı."},{"w":"upload","tr":"yüklemek (internete/bilgisayara)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move data to a larger computer system","dt":"Veriyi daha büyük bir bilgisayar sistemine taşımak","e1":"I am uploading the photos to Facebook.","e1t":"Fotoğrafları Facebook'a yüklüyorum.","e2":"The upload speed is very slow.","e2t":"Yükleme hızı çok yavaş."},{"w":"upright","tr":"dik / dürüst","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Standing straight up; or honest","dt":"Dümdüz ayakta duran; veya dürüst","e1":"Sit in an upright position.","e1t":"Dik bir pozisyonda oturun.","e2":"An upright citizen.","e2t":"Dürüst (saygın) bir vatandaş."},{"w":"upside down","tr":"baş aşağı / ters","te":"Adverb/Adjective","tt":"With the top part at the bottom","de":"Üst kısmı altta olacak şekilde","dt":"The picture is upside down.","e1":"Resim ters (baş aşağı).","e1t":"He turned the house upside down looking for his keys.","e2":"Anahtarlarını ararken evi altını üstüne getirdi.","e2t":""},{"w":"upturn","tr":"iyileşme / yükseliş","te":"Noun","tt":"İsim","de":"An improvement or increase in something","dt":"Bir şeydeki iyileşme veya artış","e1":"An upturn in the economy.","e1t":"Ekonomide bir iyileşme (yükseliş).","e2":"Sales showed a sharp upturn.","e2t":"Satışlar keskin bir yükseliş gösterdi."},{"w":"urgently","tr":"acilen","te":"Adverb","tt":"Zarf","de":"In a way that needs immediate attention","dt":"Hemen ilgilenilmesi gereken bir şekilde","e1":"We need to deal with this problem urgently.","e1t":"Bu sorunla acilen ilgilenmemiz gerekiyor.","e2":"He was urgently summoned to the hospital.","e2t":"Acilen hastaneye çağrıldı."},{"w":"useful","tr":"faydalı / yararlı","te":"Adjective","tt":"Sıfat","de":"Helping you to do or achieve something","dt":"Bir şeyi yapmanıza veya başarmanıza yardımcı olan","e1":"AI is a useful tool for teachers.","e1t":"Yapay zeka öğretmenler için faydalı bir araçtır.","e2":"A useful piece of advice.","e2t":"Yararlı bir tavsiye."},{"w":"usefulness","tr":"yararlılık / fayda","te":"Noun","tt":"İsim","de":"The quality of being useful","dt":"Faydalı olma özelliği","e1":"The usefulness of the new system.","e1t":"Yeni sistemin yararlılığı.","e2":"I doubt the usefulness of this machine.","e2t":"Bu makinenin faydasından şüphe duyuyorum."},{"w":"useless","tr":"yararsız / faydasız / beceriksiz","te":"Adjective","tt":"Sıfat","de":"Not helping at all","dt":"Hiç yardımcı olmayan","e1":"This old computer is useless.","e1t":"Bu eski bilgisayar işe yaramaz (faydasız).","e2":"I'm useless at math.","e2t":"Matematikte beceriksizim."},{"w":"user","tr":"friendly","te":"kullanıcı dostu","tt":"Adjective","de":"Sıfat","dt":"Easy for people to use","e1":"İnsanların kullanması için kolay","e1t":"A user","e2":"friendly interface.","e2t":"Kullanıcı dostu bir arayüz."},{"w":"utilization / utilisation","tr":"kullanım / faydalanma","te":"Noun","tt":"İsim","de":"The act of using something effectively","dt":"Bir şeyi etkili kullanma eylemi","e1":"The utilization of modern technology in schools.","e1t":"Okullarda modern teknoloji kullanımı.","e2":"Capacity utilization.","e2t":"Kapasite kullanımı."},{"w":"vacate","tr":"boşaltmak / terk etmek","te":"Verb","tt":"Fiil","de":"To leave a building or a seat","dt":"Bir binayı veya koltuğu boşaltmak","e1":"Please vacate your room by 11 AM.","e1t":"Lütfen odanızı saat 11'e kadar boşaltın.","e2":"He vacated his seat for the elderly lady.","e2t":"Koltuğunu yaşlı hanım için boşalttı."},{"w":"vaguely","tr":"belirsizce / hayal meyal / şöyle böyle","te":"Adverb","tt":"Zarf","de":"In a way that is not clear","dt":"Net olmayan bir şekilde","e1":"I vaguely remember meeting him.","e1t":"Onunla tanıştığımı hayal meyal hatırlıyorum.","e2":"He smiled vaguely.","e2t":"Şöyle böyle (belirsizce) gülümsedi."},{"w":"valuation","tr":"değerleme / değer biçme","te":"Noun","tt":"İsim","de":"The act of deciding how much something is worth","dt":"Bir şeyin ne kadar ettiğine karar verme eylemi","e1":"Property valuation.","e1t":"Emlak değerlemesi.","e2":"Professional valuation.","e2t":"Profesyonel değer tespiti."},{"w":"vanilla","tr":"vanilya","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance used to flavor food","dt":"Yiyeceklere lezzet vermek için kullanılan madde","e1":"Vanilla ice cream.","e1t":"Vanilyalı dondurma.","e2":"Vanilla extract.","e2t":"Vanilya özütü."},{"w":"vary","tr":"değişmek / çeşitlilik göstermek","te":"Verb","tt":"Fiil","de":"To change or to be different","dt":"Değişmek veya farklı olmak","e1":"Prices vary depending on the season.","e1t":"Fiyatlar mevsime göre değişir.","e2":"The menu varies every day.","e2t":"Menü her gün değişiyor."},{"w":"vase","tr":"vazo","te":"Noun","tt":"İsim","de":"A container used for holding flowers","dt":"Çiçek koymak için kullanılan kap","e1":"Put the flowers in a vase.","e1t":"Çiçekleri bir vazoya koy.","e2":"A glass vase.","e2t":"Cam vazo."},{"w":"vastly","tr":"çok fazla / muazzam derecede","te":"Adverb","tt":"Zarf","de":"Very much","dt":"Çok fazla","e1":"The quality has improved vastly.","e1t":"Kalite muazzam derecede arttı.","e2":"He is vastly experienced.","e2t":"O çok fazla (derin) tecrübeye sahip."},{"w":"veal","tr":"dana eti","te":"Noun","tt":"İsim","de":"Meat from a young cow","dt":"Genç sığır (buzağı) eti","e1":"We had veal cutlets for dinner.","e1t":"Akşam yemeğinde dana pirzola yedik.","e2":"Veal stew.","e2t":"Dana yahni."},{"w":"vend","tr":"satmak (otomat vb. ile)","te":"Verb","tt":"Fiil","de":"To sell something","dt":"Bir şey satmak","e1":"Vending machine.","e1t":"Otomat (satış makinesi).","e2":"Licensed to vend goods on the street.","e2t":"Sokakta mal satmak için lisanslı."},{"w":"venerate","tr":"çok saygı duymak / kutsallaştırmak","te":"Verb","tt":"Fiil","de":"To respect or worship someone very much","dt":"Birine çok saygı duymak veya tapınmak","e1":"The monks venerate their ancestors.","e1t":"Keşişler atalarına büyük saygı duyarlar (kutsallaştırırlar).","e2":"He is venerated as a saint.","e2t":"Bir aziz olarak saygı görür."},{"w":"vengeance","tr":"intikam / öç","te":"Noun","tt":"İsim","de":"Revenge for a wrong done to you","dt":"Size yapılan bir yanlışa karşı alınan intikam","e1":"He swore vengeance on his enemies.","e1t":"Düşmanlarından intikam alacağına yemin etti.","e2":"With a vengeance (with great force).","e2t":"Şiddetle (büyük bir hırsla)."},{"w":"ventilator","tr":"vantilatör / solunum cihazı","te":"Noun","tt":"İsim","de":"A device used for ventilation","dt":"Havalandırma için kullanılan cihaz","e1":"He was put on a ventilator.","e1t":"Solunum cihazına bağlandı.","e2":"Ceiling ventilator.","e2t":"Tavan pervanesi (havalandırıcısı)."},{"w":"verbal","tr":"sözlü","te":"Adjective","tt":"Sıfat","de":"Relating to words or spoken rather than written","dt":"Kelimelerle ilgili olan veya yazılıdan ziyade sözlü olan","e1":"A verbal agreement.","e1t":"Sözlü bir anlaşma.","e2":"Verbal communication.","e2t":"Sözlü iletişim."},{"w":"verbally","tr":"sözlü olarak","te":"Adverb","tt":"Zarf","de":"In a spoken way","dt":"Konuşarak (sözlü bir şekilde)","e1":"He was verbally abused.","e1t":"Sözlü tacize uğradı.","e2":"They agreed verbally.","e2t":"Sözlü olarak anlaştılar."},{"w":"vermin","tr":"zararlı hayvan / haşere","te":"Noun","tt":"İsim","de":"Small animals or insects that are harmful","dt":"Zararlı olan küçük hayvanlar veya böcekler","e1":"Rats and mice are vermin.","e1t":"Sıçanlar ve fareler haşeredir.","e2":"The garden is infested with vermin.","e2t":"Bahçeyi haşereler istila etmiş."},{"w":"vertically","tr":"dikey olarak","te":"Adverb","tt":"Zarf","de":"In a vertical way","dt":"Dikey bir biçimde","e1":"The boxes were stacked vertically.","e1t":"Kutular dikey olarak istiflenmişti.","e2":"Hold the phone vertically.","e2t":"Telefonu dikey tut."},{"w":"veteran","tr":"kıdemli / emektar / gazi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has a lot of experience; or an ex","dt":"soldier","e1":"Çok deneyimli kişi; veya eski asker","e1t":"A war veteran.","e2":"Savaş gazisi.","e2t":"He is a veteran teacher."},{"w":"veterinarian / vet","tr":"veteriner","te":"Noun","tt":"İsim","de":"A doctor for animals","dt":"Hayvan doktoru","e1":"Take the cat to the vet.","e1t":"Kediyi veterinere götür.","e2":"She wants to be a veterinarian.","e2t":"Veteriner olmak istiyor."},{"w":"vicar","tr":"papaz / vekil","te":"Noun","tt":"İsim","de":"A priest in the Church of England","dt":"İngiliz Kilisesi'ndeki papaz","e1":"The vicar gave a sermon.","e1t":"Papaz bir vaaz verdi.","e2":"Vicar general.","e2t":"Genel vekil."},{"w":"vice","tr":"kusur / yardımcısı / ahlaksızlık / mengene","te":"Noun/Adjective/Prep","tt":"A bad habit; or a person who is next in rank","de":"Kötü alışkanlık; veya rütbece bir sonraki kişi","dt":"Smoking is my only vice.","e1":"Sigara içmek benim tek kusurum (kötü alışkanlığım).","e1t":"Vice president.","e2":"Başkan yardımcısı.","e2t":""},{"w":"victimize / victimise","tr":"mağdur etmek / kurban etmek","te":"Verb","tt":"Fiil","de":"To treat someone unfairly","dt":"Birine adaletsiz davranmak","e1":"He claimed he was victimized by his boss.","e1t":"Patronu tarafından mağdur edildiğini iddia etti.","e2":"To avoid victimizing the innocent.","e2t":"Masumları mağdur etmekten kaçınmak."},{"w":"video","tr":"video / video çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Recording of moving pictures and sounds","dt":"Hareketli görüntü ve ses kaydı","e1":"I watched a video on YouTube.","e1t":"YouTube'da bir video izledim.","e2":"He videos all his travels.","e2t":"Tüm seyahatlerini videoya çekiyor."},{"w":"vigilance","tr":"uyanıklık / teyakkuz / dikkat","te":"Noun","tt":"İsim","de":"Careful attention to notice possible danger","dt":"Olası tehlikeyi fark etmek için dikkatli olma hali","e1":"The police called for public vigilance.","e1t":"Polis halkı uyanık olmaya (teyakkuzda kalmaya) çağırdı.","e2":"Constant vigilance.","e2t":"Sürekli dikkat."},{"w":"vigilant","tr":"uyanık / dikkatli / tetikte","te":"Adjective","tt":"Sıfat","de":"Always careful to notice danger","dt":"Tehlikeyi fark etmek için her zaman dikkatli olan","e1":"We must remain vigilant.","e1t":"Tetikte (dikkatli) kalmalıyız.","e2":"A vigilant security guard.","e2t":"Dikkatli bir güvenlik görevlisi."},{"w":"vile","tr":"aşağılık / iğrenç / berbat","te":"Adjective","tt":"Sıfat","de":"Extremely unpleasant or immoral","dt":"Son derece nahoş veya ahlaksız","e1":"A vile smell.","e1t":"İğrenç bir koku.","e2":"He has a vile temper.","e2t":"Berbat (çok kötü) bir huyu var."},{"w":"villager","tr":"köylü","te":"Noun","tt":"İsim","de":"A person who lives in a village","dt":"Köyde yaşayan kişi","e1":"The villagers were very hospitable.","e1t":"Köylüler çok misafirperverdi.","e2":"Local villagers.","e2t":"Yerel köylüler."},{"w":"villain","tr":"kötü adam / hain","te":"Noun","tt":"İsim","de":"A character in a book or movie who does bad things","dt":"Kitap veya filmdeki kötü karakter","e1":"He played the villain in the movie.","e1t":"Filmde kötü adamı oynadı.","e2":"The villain's plan was foiled.","e2t":"Hainin planı bozuldu."},{"w":"violently","tr":"şiddetle / sert bir şekilde","te":"Adverb","tt":"Zarf","de":"In a violent way","dt":"Şiddetli bir biçimde","e1":"The wind blew violently.","e1t":"Rüzgar şiddetle esti.","e2":"He reacted violently to the news.","e2t":"Haberlere sert bir şekilde tepki verdi."},{"w":"virtuous","tr":"erdemli / namuslu","te":"Adjective","tt":"Sıfat","de":"Having high moral standards","dt":"Yüksek ahlaki standartlara sahip olan","e1":"He led a virtuous life.","e1t":"Erdemli bir hayat sürdü.","e2":"A virtuous woman.","e2t":"Erdemli bir kadın."},{"w":"visibility","tr":"görünürlük / görüş mesafesi","te":"Noun","tt":"İsim","de":"The ability to see or be seen","dt":"Görme veya görülme yeteneği","e1":"Visibility was poor due to the fog.","e1t":"Sis nedeniyle görüş mesafesi zayıftı.","e2":"High","e2t":"visibility clothing."},{"w":"visibly","tr":"gözle görülür bir şekilde","te":"Adverb","tt":"Zarf","de":"In a way that can be seen","dt":"Görülebilir bir biçimde","e1":"He was visibly upset.","e1t":"Gözle görülür bir şekilde üzgündü.","e2":"The city has changed visibly.","e2t":"Şehir gözle görülür şekilde değişti."},{"w":"visually","tr":"görsel olarak","te":"Adverb","tt":"Zarf","de":"In a visual way","dt":"Görsel bir biçimde","e1":"The movie is visually stunning.","e1t":"Film görsel olarak büyüleyici.","e2":"Visually impaired (blind).","e2t":"Görme engelli."},{"w":"vitality","tr":"canlılık / zindelik / hayat enerjisi","te":"Noun","tt":"İsim","de":"Energy and strength","dt":"Enerji ve güç","e1":"Exercises can improve your vitality.","e1t":"Egzersizler zindeliğinizi artırabilir.","e2":"Full of vitality.","e2t":"Hayat enerjisiyle dolu."},{"w":"vocabulary","tr":"kelime hazinesi / sözcük dağarcığı","te":"Noun","tt":"İsim","de":"All the words that a person knows or uses","dt":"Bir kişinin bildiği veya kullandığı tüm kelimeler","e1":"You need to expand your English vocabulary.","e1t":"İngilizce kelime hazineni genişletmen gerekiyor.","e2":"Academic vocabulary.","e2t":"Akademik kelime dağarcığı."},{"w":"volatility","tr":"oynaklık / değişkenlik / uçuculuk","te":"Noun","tt":"İsim","de":"The quality of being likely to change suddenly","dt":"Aniden değişme olasılığı olma özelliği","e1":"Market volatility.","e1t":"Piyasa oynaklığı (değişkenliği).","e2":"The volatility of fuel.","e2t":"Yakıtın uçuculuğu."},{"w":"volley","tr":"voley (top yere değmeden vurmak) / yaylım ateşi","te":"Noun/Verb","tt":"İsim/Fiil","de":"Hitting a ball before it touches the ground","dt":"Top yere değmeden önce vurmak","e1":"He scored with a spectacular volley.","e1t":"Muhteşem bir voley ile gol attı.","e2":"A volley of questions.","e2t":"Soru yağmuru."},{"w":"volleyball","tr":"voleybol","te":"Noun","tt":"İsim","de":"A game played by two teams over a high net","dt":"Yüksek bir filenin üzerinden iki takımca oynanan oyun","e1":"Do you want to play volleyball?","e1t":"Voleybol oynamak ister misin?","e2":"Volleyball court.","e2t":"Voleybol sahası."},{"w":"wagon","tr":"vagon / at arabası / el arabası","te":"Noun","tt":"İsim","de":"A vehicle for carrying heavy loads","dt":"Ağır yük taşımak için kullanılan araç","e1":"A railway wagon.","e1t":"Demiryolu vagonu.","e2":"The pioneers traveled in wagons.","e2t":"Öncüler at arabalarıyla (vagonlarla) seyahat etti."},{"w":"waitress","tr":"garson (kadın)","te":"Noun","tt":"İsim","de":"A woman who serves food and drinks in a restaurant","dt":"Restoranda yemek ve içecek servisi yapan kadın","e1":"The waitress was very polite.","e1t":"Garson hanım çok nazikti.","e2":"She is a part","e2t":"time waitress."},{"w":"wake up","tr":"uyanmak / uyandırmak","te":"Verb","tt":"Fiil","de":"To stop sleeping","dt":"Uyumayı bırakmak","e1":"I wake up at 7 AM every day.","e1t":"Her gün saat 7'de uyanırım.","e2":"Wake me up when you're ready.","e2t":"Hazır olduğunda beni uyandır."},{"w":"walkway","tr":"yaya yolu / geçit","te":"Noun","tt":"İsim","de":"A path for walking","dt":"Yürüyüş yolu","e1":"A covered walkway.","e1t":"Kapalı yaya geçidi.","e2":"The coastal walkway.","e2t":"Sahil yürüyüş yolu."},{"w":"warmly","tr":"sıcak bir şekilde / içtenlikle","te":"Adverb","tt":"Zarf","de":"In a warm way","dt":"Samimi bir biçimde","e1":"He greeted us warmly.","e1t":"Bizi sıcak bir şekilde karşıladı.","e2":"Dress warmly, it's cold outside.","e2t":"Sıkı (sıcak tutacak şekilde) giyin, dışarısı soğuk."},{"w":"warmth","tr":"sıcaklık / içtenlik","te":"Noun","tt":"İsim","de":"The state or quality of being warm","dt":"Sıcak olma durumu veya özelliği","e1":"The warmth of the sun.","e1t":"Güneşin sıcaklığı.","e2":"I appreciate your warmth and kindness.","e2t":"İçtenliğin ve nezaketin için minnettarım."},{"w":"warship","tr":"savaş gemisi","te":"Noun","tt":"İsim","de":"A ship designed for use in war","dt":"Savaş için tasarlanmış gemi","e1":"The warship was patrolling the coast.","e1t":"Savaş gemisi kıyıda devriye geziyordu.","e2":"Aircraft carrier is a large warship.","e2t":"Uçak gemisi büyük bir savaş gemisidir."},{"w":"wartime","tr":"savaş zamanı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A period of time when a war is happening","dt":"Savaşın gerçekleştiği dönem","e1":"Wartime memories.","e1t":"Savaş zamanı anıları.","e2":"During wartime.","e2t":"Savaş sırasında."},{"w":"wash","tr":"yıkamak / yıkanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To clean something with water","dt":"Suyla temizlemek","e1":"Wash your hands before eating.","e1t":"Yemekten önce ellerini yıka.","e2":"I need to do the wash (laundry).","e2t":"Çamaşırları yıkamam (çamaşır yapmam) gerekiyor."},{"w":"washing machine","tr":"çamaşır makinesi","te":"Noun","tt":"İsim","de":"A machine for washing clothes","dt":"Çamaşır yıkama makinesi","e1":"Put the dirty clothes in the washing machine.","e1t":"Kirli çamaşırları çamaşır makinesine koy.","e2":"Automatic washing machine.","e2t":"Otomatik çamaşır makinesi."},{"w":"wasteful","tr":"müsrif / savurgan","te":"Adjective","tt":"Sıfat","de":"Using more of something than is necessary","dt":"Bir şeyi gereğinden fazla kullanan","e1":"It is wasteful to leave the lights on.","e1t":"Işıkları açık bırakmak müsrifliktir.","e2":"A wasteful lifestyle.","e2t":"Savurgan bir yaşam tarzı."},{"w":"watchdog","tr":"denetçi / bekçi köpeği","te":"Noun","tt":"İsim","de":"A person or organization that monitors others","dt":"Başkalarını izleyen (denetleyen) kişi veya kuruluş","e1":"Consumer watchdog.","e1t":"Tüketici hakları denetçisi.","e2":"Financial watchdog.","e2t":"Finansal denetleme kurulu."},{"w":"watchman","tr":"bekçi","te":"Noun","tt":"İsim","de":"A person whose job is to guard a building","dt":"İşi bir binayı korumak olan kişi","e1":"The night watchman was asleep.","e1t":"Gece bekçisi uyuyordu.","e2":"Security watchman.","e2t":"Güvenlik bekçisi."},{"w":"wear","tr":"giymek / takmak / aşınmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To have clothing on your body; or to damage by use","dt":"Vücudunda kıyafet olması; veya kullanarak zarar vermek/eskimek","e1":"What are you going to wear?","e1t":"Ne giyeceksin?","e2":"Wear and tear.","e2t":"Aşınma ve yıpranma."},{"w":"weather forecast","tr":"hava durumu tahmini","te":"Noun","tt":"İsim","de":"A description of what the weather will be like","dt":"Havanın nasıl olacağına dair açıklama","e1":"Have you heard the weather forecast for tomorrow?","e1t":"Yarın için hava durumu tahminini duydun mu?","e2":"The weather forecast predicts rain.","e2t":"Hava durumu tahmini yağmur öngörüyor."},{"w":"weekday","tr":"hafta içi gün","te":"Noun","tt":"İsim","de":"Any day of the week except Saturday and Sunday","dt":"Cumartesi ve Pazar hariç haftanın herhangi bir günü","e1":"I work on weekdays.","e1t":"Hafta içleri çalışırım.","e2":"Most shops are open on weekdays.","e2t":"Çoğu dükkan hafta içleri açıktır."},{"w":"weekend","tr":"hafta sonu","te":"Noun/Verb/Adj","tt":"Saturday and Sunday","de":"Cumartesi ve Pazar","dt":"What are you doing this weekend?","e1":"Bu hafta sonu ne yapıyorsun?","e1t":"Have a nice weekend!","e2":"İyi hafta sonları!","e2t":""},{"w":"weekly","tr":"haftalık","te":"Adjective/Adverb/Noun","tt":"Happening once a week","de":"Haftada bir kez olan","dt":"A weekly magazine.","e1":"Haftalık bir dergi.","e1t":"The bill is paid weekly.","e2":"Fatura haftalık ödenir.","e2t":""},{"w":"weighty","tr":"ağır / önemli / ciddi","te":"Adjective","tt":"Sıfat","de":"Heavy; or very serious and important","dt":"Ağır; veya çok ciddi ve önemli","e1":"A weighty decision.","e1t":"Önemli (ağır) bir karar.","e2":"Weighty matters of state.","e2t":"Devletin ciddi meseleleri."},{"w":"well","tr":"known","te":"ünlü / iyi bilinen","tt":"Adjective","de":"Sıfat","dt":"Known by many people","e1":"Birçok kişi tarafından bilinen","e1t":"He is a well","e2":"known actor.","e2t":"O ünlü bir aktördür."},{"w":"western","tr":"batılı / batıya ait / kovboy filmi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the west","dt":"Batı ile ilgili","e1":"Western culture.","e1t":"Batı kültürü.","e2":"I like watching old westerns.","e2t":"Eski kovboy filmlerini (western) izlemeyi severim."},{"w":"wet","tr":"ıslak / yaş / ıslatmak","te":"Adjective/Verb/Noun","tt":"Covered with liquid","de":"Sıvıyla kaplı","dt":"Don't sit on the wet grass.","e1":"Islak çimlere oturma.","e1t":"Wet paint!","e2":"Boya yaş (yeni boyanmış)!","e2t":""},{"w":"whoever","tr":"her kim / kim olursa","te":"Pronoun","tt":"Zamir","de":"Any person who","dt":"Her kim ... ise","e1":"Whoever told you that was lying.","e1t":"Sana onu her kim söylediyse yalan söylüyordu.","e2":"You can bring whoever you want.","e2t":"Kimi istersen (her kimi) getirebilirsin."},{"w":"wholesale","tr":"toptan / toptan satış","te":"Noun/Adjective/Adverb","tt":"The business of selling goods in large quantities to shopkeepers","de":"Malların dükkan sahiplerine büyük miktarlarda satılması işi","dt":"We buy our supplies at wholesale prices.","e1":"Malzemelerimizi toptan fiyatına alıyoruz.","e1t":"Wholesale trade.","e2":"Toptan ticaret.","e2t":""},{"w":"wholesaler","tr":"toptancı","te":"Noun","tt":"İsim","de":"A person or company that sells goods wholesale","dt":"Malları toptan satan kişi veya şirket","e1":"He is a leading fruit and vegetable wholesaler.","e1t":"O, önde gelen bir meyve ve sebze toptancısıdır.","e2":"Contact the wholesaler for a discount.","e2t":"İndirim için toptancıyla iletişime geçin."},{"w":"widow","tr":"dul (kadın)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A woman whose husband has died","dt":"Kocası ölmüş kadın","e1":"She has been a widow for ten years.","e1t":"On yıldır dul.","e2":"War widows.","e2t":"Savaş dulları."},{"w":"widower","tr":"dul (erkek)","te":"Noun","tt":"İsim","de":"A man whose wife has died","dt":"Karısı ölmüş erkek","e1":"He became a widower last year.","e1t":"Geçen yıl dul kaldı.","e2":"The lonely widower.","e2t":"Yalnız dul adam."},{"w":"wilderness","tr":"yaban hayatı / ıssız yer / çöl","te":"Noun","tt":"İsim","de":"An outside area where people do not live","dt":"İnsanların yaşamadığı dış alan (doğa)","e1":"We went hiking in the wilderness.","e1t":"Yaban hayatında (ıssız doğada) yürüyüşe çıktık.","e2":"To protect the mountain wilderness.","e2t":"Dağlık yaban alanlarını korumak."},{"w":"willingly","tr":"isteyerek / seve seve","te":"Adverb","tt":"Zarf","de":"In a willing way","dt":"İsteyerek (kendi rızasıyla)","e1":"He willingly accepted the offer.","e1t":"Teklifi seve seve kabul etti.","e2":"I would willingly go there again.","e2t":"Oraya seve seve tekrar giderim."},{"w":"wooden","tr":"ahşap / tahta","te":"Adjective","tt":"Sıfat","de":"Made of wood","dt":"Tahtadan yapılmış","e1":"A wooden chair.","e1t":"Ahşap bir sandalye.","e2":"A small wooden house.","e2t":"Küçük bir tahta ev."},{"w":"work register","tr":"iş kayıt defteri / puantaj","te":"Noun","tt":"İsim","de":"A record of work done or attendance","dt":"Yapılan işin veya katılımın kaydı","e1":"Please sign the work register.","e1t":"Lütfen iş kayıt defterini imzalayın.","e2":"We check the work register every morning.","e2t":"Her sabah iş kayıtlarını kontrol ederiz."},{"w":"workforce","tr":"iş gücü","te":"Noun","tt":"İsim","de":"All the people who work in a company or country","dt":"Bir şirkette veya ülkede çalışan tüm insanlar","e1":"A highly skilled workforce.","e1t":"Yüksek vasıflı bir iş gücü.","e2":"The female workforce is increasing.","e2t":"Kadın iş gücü artıyor."},{"w":"workout","tr":"antrenman / egzersiz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A period of physical exercise","dt":"Fiziksel egzersiz süresi","e1":"I have a daily workout routine.","e1t":"Günlük bir antrenman rutinim var.","e2":"Morning workout.","e2t":"Sabah egzersizi."},{"w":"worldwide","tr":"dünya çapında","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Existing or happening in all parts of the world","dt":"Dünyanın her yerinde var olan veya gerçekleşen","e1":"The company has a worldwide reputation.","e1t":"Şirketin dünya çapında bir ünü var.","e2":"The movie was a worldwide success.","e2t":"Film dünya çapında bir başarıydı."},{"w":"worse","tr":"daha kötü","te":"Adjective/Adverb/Noun","tt":"Comparative of \"bad\"","de":"\"Bad\" (kötü) kelimesinin karşılaştırma hali","dt":"The weather is worse than yesterday.","e1":"Hava dünden daha kötü.","e1t":"From bad to worse.","e2":"Kötüden daha kötüye.","e2t":""},{"w":"worst","tr":"en kötü","te":"Adjective/Adverb/Noun","tt":"Superlative of \"bad\"","de":"\"Bad\" (kötü) kelimesinin en üstünlük hali","dt":"This is the worst movie I've ever seen.","e1":"Bu şimdiye kadar gördüğüm en kötü film.","e1t":"At worst.","e2":"En kötü ihtimalle.","e2t":""},{"w":"worthless","tr":"değersiz","te":"Adjective","tt":"Sıfat","de":"Having no value","dt":"Hiç değeri olmayan","e1":"The old coins are worthless.","e1t":"Eski paralar değersiz.","e2":"I felt worthless after the failure.","e2t":"Başarısızlıktan sonra kendimi değersiz hissettim."},{"w":"wrong","tr":"yanlış / hatalı / haksızlık","te":"Adjective/Adverb/Noun/Verb","tt":"Not correct or not fair","de":"Doğru veya adil olmayan","dt":"This is the wrong answer.","e1":"Bu yanlış cevap.","e1t":"What is wrong with you?","e2":"Senin neyin var (neyin yanlış)?","e2t":""},{"w":"wrongly","tr":"yanlışlıkla / haksız yere","te":"Adverb","tt":"Zarf","de":"In a way that is not correct or fair","dt":"Doğru veya adil olmayan bir şekilde","e1":"He was wrongly accused of the crime.","e1t":"Suçla haksız yere itham edildi.","e2":"I was wrongly informed.","e2t":"Yanlış bilgilendirildim."},{"w":"yearly","tr":"yıllık","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Happening once a year","dt":"Yılda bir kez olan","e1":"A yearly report.","e1t":"Yıllık bir rapor.","e2":"The festival is held yearly.","e2t":"Festival her yıl düzenlenir."},{"w":"yearn","tr":"özlemek / can atmak / hasret çekmek","te":"Verb","tt":"Fiil","de":"To wish very strongly for something","dt":"Bir şeyi çok güçlü bir şekilde istemek","e1":"He yearns for his homeland.","e1t":"Vatanına hasret çekiyor.","e2":"I yearn to see her again.","e2t":"Onu tekrar görmeye can atıyorum."},{"w":"yoga","tr":"yoga","te":"Noun","tt":"İsim","de":"A system of exercises for physical and mental health","dt":"Fiziksel ve zihinsel sağlık için bir egzersiz sistemi","e1":"I do yoga every morning to stay flexible.","e1t":"Esnek kalmak için her sabah yoga yapıyorum.","e2":"Yoga instructor.","e2t":"Yoga eğitmeni."},{"w":"yoghurt / yogurt","tr":"yoğurt","te":"Noun","tt":"İsim","de":"A thick liquid food made from milk","dt":"Sütten yapılan koyu kıvamlı gıda","e1":"Turkish yoghurt is famous worldwide.","e1t":"Türk yoğurdu dünya çapında ünlüdür.","e2":"Fruit yoghurt.","e2t":"Meyveli yoğurt."},{"w":"youngster","tr":"genç / çocuk / ufaklık","te":"Noun","tt":"İsim","de":"A young person or a child","dt":"Genç bir kişi veya çocuk","e1":"The youngsters in our neighborhood love football.","e1t":"Mahallemizdeki gençler futbolu severler.","e2":"A talented youngster.","e2t":"Yetenekli bir genç."},{"w":"youthful","tr":"genç / dinç / genç görünen","te":"Adjective","tt":"Sıfat","de":"Having the qualities of a young person","dt":"Bir gencin özelliklerine sahip olan (dinç)","e1":"She has a very youthful appearance.","e1t":"Çok genç bir görünümü var.","e2":"Youthful energy.","e2t":"Gençlik enerjisi."},{"w":"zebra","tr":"zebra","te":"Noun","tt":"İsim","de":"A wild African animal like a horse with black and white stripes","dt":"Siyah beyaz çizgili, at benzeri vahşi Afrika hayvanı","e1":"Zebras live in large herds.","e1t":"Zebralar büyük sürüler halinde yaşarlar.","e2":"Zebra crossing (pedestrian crossing).","e2t":"Yaya geçidi (zebra çizgili)."},{"w":"zigzag","tr":"zikzak / zikzak yapmak","te":"Noun/Adjective/Verb","tt":"A line or path that has a series of sharp turns","de":"Bir dizi keskin dönüşü olan çizgi veya yol","dt":"The path zigzags up the mountain.","e1":"Patika dağa zikzaklar çizerek çıkıyor.","e1t":"A zigzag pattern.","e2":"Zikzak desen.","e2t":""},{"w":"zip / zipper","tr":"fermuar / fermuar çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device used for fastening clothes","dt":"Kıyafetleri bağlamak/kapatmak için kullanılan düzenek","e1":"Your zip is open.","e1t":"Fermuarın açık.","e2":"Zip up your jacket, it's cold.","e2t":"Ceketinin fermuarını çek, hava soğuk."},{"w":"b2","tr":"","te":"","tt":"","de":"","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"abundant","tr":"bol / çok / bereketli","te":"Adjective","tt":"Sıfat","de":"Existing in large quantities","dt":"Büyük miktarlarda var olan","e1":"Turkey has abundant natural resources.","e1t":"Türkiye bol doğal kaynaklara sahiptir.","e2":"There is abundant evidence of climate change.","e2t":"İklim değişikliğine dair bolca kanıt var."},{"w":"accelerate","tr":"hızlanmak / hızlandırmak","te":"Verb","tt":"Fiil","de":"To happen or make something happen faster","dt":"Daha hızlı gerçekleşmek veya hızlandırmak","e1":"The car accelerated as it left the city.","e1t":"Şehir dışına çıkarken araba hızlandı.","e2":"Technology accelerates the learning process.","e2t":"Teknoloji, öğrenme sürecini hızlandırır."},{"w":"accommodate","tr":"barındırmak / yer sağlamak / uyum sağlamak","te":"Verb","tt":"Fiil","de":"To provide a place to stay or to fit in","dt":"Kalacak yer sağlamak veya uyum sağlamak","e1":"The hotel can accommodate up to 500 guests.","e1t":"Otel 500 misafire kadar barındırabilir.","e2":"We need to accommodate the needs of all students.","e2t":"Tüm öğrencilerin ihtiyaçlarına uyum sağlamalıyız (yer vermeliyiz)."},{"w":"accountability","tr":"hesap verebilirlik / sorumluluk","te":"Noun","tt":"İsim","de":"The fact of being responsible for what you do","dt":"Yaptıklarından sorumlu olma durumu","e1":"There is a lack of accountability in the management.","e1t":"Yönetimde bir hesap verebilirlik eksiklikliği var.","e2":"Public accountability is vital for democracy.","e2t":"Kamu hesap verebilirliği demokrasi için hayatidir."},{"w":"accumulate","tr":"biriktirmek / birikmek / toplamak","te":"Verb","tt":"Fiil","de":"To collect or increase something over time","dt":"Zamanla bir şeyi toplamak veya artırmak","e1":"You can accumulate points as you play the game.","e1t":"Oyunu oynadıkça puan biriktirebilirsiniz.","e2":"Dust began to accumulate on the old books.","e2t":"Eski kitapların üzerinde toz birikmeye başladı."},{"w":"acquisition","tr":"edinim / kazanç / şirket alımı","te":"Noun","tt":"İsim","de":"The act of getting something","dt":"Bir şeyi elde etme eylemi","e1":"Language acquisition starts at a young age.","e1t":"Dil edinimi genç yaşta başlar.","e2":"The company's latest acquisition was a small tech firm.","e2t":"Şirketin son edinimi (satın aldığı şey) küçük bir teknoloji firmasıydı."},{"w":"acute","tr":"şiddetli / keskin / dar (açı)","te":"Adjective","tt":"Sıfat","de":"Very serious or sharp","dt":"Çok ciddi veya keskin","e1":"She is suffering from acute back pain.","e1t":"Şiddetli bel ağrısı çekiyor.","e2":"An acute angle is less than 90 degrees.","e2t":"Dar açı 90 dereceden küçüktür."},{"w":"addict","tr":"bağımlı / meraklı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who cannot stop doing or using something","dt":"Bir şeyi yapmayı veya kullanmayı bırakamayan kişi","e1":"A computer game addict.","e1t":"Bir bilgisayar oyunu bağımlısı.","e2":"He is a coffee addict.","e2t":"O bir kahve bağımlısı (meraklısı)."},{"w":"adhere","tr":"bağlı kalmak / yapışmak","te":"Verb","tt":"Fiil","de":"To stick firmly or to follow a rule","dt":"Sıkıca yapışmak veya bir kuralı takip etmek","e1":"You must adhere to the safety regulations.","e1t":"Güvenlik kurallarına bağlı kalmalısınız.","e2":"The paint will not adhere to a greasy surface.","e2t":"Boya yağlı bir yüzeye yapışmaz."},{"w":"adjacent","tr":"bitişik / komşu / yan yana","te":"Adjective","tt":"Sıfat","de":"Very near, next to, or touching","dt":"Çok yakın, yanında veya temas eden","e1":"The school is adjacent to the park.","e1t":"Okul parkın bitişiğindedir.","e2":"We have adjacent rooms in the hotel.","e2t":"Otelde yan yana (bitişik) odalarımız var."},{"w":"aesthetic","tr":"estetik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to beauty or the study of beauty","dt":"Güzellik veya güzellik felsefesiyle ilgili","e1":"The building has great aesthetic appeal.","e1t":"Binanın harika bir estetik çekiciliği var.","e2":"From an aesthetic point of view.","e2t":"Estetik bir bakış açısından."},{"w":"affluence","tr":"zenginlik / bolluk / refah","te":"Noun","tt":"İsim","de":"The state of having a lot of money or possessions","dt":"Çok paraya veya mülke sahip olma durumu","e1":"A sign of growing affluence in the country.","e1t":"Ülkede artan refahın (zenginliğin) bir işareti.","e2":"They live in a period of relative affluence.","e2t":"Nispi bir bolluk dönemi içinde yaşıyorlar."},{"w":"afterthought","tr":"sonradan akla gelen düşünce","te":"Noun","tt":"İsim","de":"A thought that comes after something has been done or said","dt":"Bir şey yapıldıktan veya söylendikten sonra akla gelen fikir","e1":"He added the signature as an afterthought.","e1t":"İmzayı sonradan akla gelen bir düşünceyle ekledi.","e2":"Merely an afterthought.","e2t":"Sadece sonradan düşünülmüş bir şey."},{"w":"agent","tr":"etken / temsilci / ajan","te":"Noun","tt":"İsim","de":"A person who acts for another or a substance that causes change","dt":"Başkası adına hareket eden kişi veya değişime neden olan madde","e1":"Travel agent.","e1t":"Seyahat acentesi (temsilcisi).","e2":"Cleaning agents.","e2t":"Temizlik maddeleri (etken maddeler)."},{"w":"airtight","tr":"hava sızdırmaz","te":"Adjective","tt":"Sıfat","de":"Not allowing air to escape or enter; or having no flaws","dt":"Havanın girip çıkmasına izin vermeyen; veya kusursuz/açıksız","e1":"Store the cookies in an airtight container.","e1t":"Kurabiyeleri hava sızdırmaz bir kapta saklayın.","e2":"Airtight alibi.","e2t":"Kusursuz (çürütülemez) mazeret."},{"w":"alienate","tr":"yabancılaştırmak / uzaklaştırmak","te":"Verb","tt":"Fiil","de":"To make someone feel that they do not belong","dt":"Birinin kendini ait hissetmemesine neden olmak","e1":"His comments alienated his colleagues.","e1t":"Yorumları meslektaşlarını kendinden uzaklaştırdı (yabancılaştırdı).","e2":"The new policy alienated many voters.","e2t":"Yeni politika birçok seçmeni uzaklaştırdı."},{"w":"allergic","tr":"alerjik","te":"Adjective","tt":"Sıfat","de":"Caused by or relating to an allergy","dt":"Alerji ile ilgili veya alerjiden kaynaklanan","e1":"I am allergic to cat hair.","e1t":"Kedi tüyüne alerjim var.","e2":"Allergic reaction.","e2t":"Alerjik reaksiyon."},{"w":"alleviate","tr":"hafifletmek / dindirmek","te":"Verb","tt":"Fiil","de":"To make something bad less severe","dt":"Kötü bir şeyi daha az şiddetli hale getirmek","e1":"The medicine will alleviate the pain.","e1t":"İlaç ağrıyı hafifletecektir.","e2":"Measures to alleviate poverty.","e2t":"Yoksulluğu hafifletmek için önlemler."},{"w":"allocate","tr":"tahsis etmek / ayırmak","te":"Verb","tt":"Fiil","de":"To give something officially for a purpose","dt":"Bir amaç için resmi olarak bir şey vermek","e1":"We need to allocate more resources to this project.","e1t":"Bu projeye daha fazla kaynak tahsis etmeliyiz.","e2":"The government allocated funds for the new school.","e2t":"Hükümet yeni okul için fon ayırdı."},{"w":"allowance","tr":"harçlık / ödenek / tolerans","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money that is allowed; or a limit","dt":"Verilen para miktarı; veya belirli bir limit/tolerans","e1":"I get a monthly allowance from my parents.","e1t":"Ailemden aylık harçlık alıyorum.","e2":"Baggage allowance.","e2t":"Bagaj hakkı (limiti)."},{"w":"alongside","tr":"yanında / yanı başında","te":"Preposition/Adverb","tt":"Edat/Zarf","de":"Close to the side of; or together with","dt":"Bir şeyin hemen yanında; veya biriyle birlikte","e1":"The boat pulled up alongside the pier.","e1t":"Tekne iskelenin yanına yanaştı.","e2":"Work alongside experts.","e2t":"Uzmanlarla birlikte çalışmak."},{"w":"alteration","tr":"değişiklik / tadilat","te":"Noun","tt":"İsim","de":"A change or modification","dt":"Değişim veya düzeltme","e1":"The dress needs some alterations.","e1t":"Elbisenin biraz tadilata ihtiyacı var.","e2":"Major alteration.","e2t":"Büyük değişiklik."},{"w":"alternate","tr":"ardışık / dönüşümlü / yedek","te":"Verb/Noun/Adj","tt":"To happen one after another or to take turns","de":"Birbiri ardına gelmek veya sırayla yapmak","dt":"Rain alternated with sunshine.","e1":"Yağmur ve güneş dönüşümlü olarak geldi.","e1t":"Alternate layers of cake and cream.","e2":"Ardışık kek ve krema katmanları.","e2t":""},{"w":"amateur","tr":"amatör","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Doing something for pleasure, not as a job","dt":"Bir şeyi iş olarak değil, zevk için yapan","e1":"He is an amateur photographer.","e1t":"O amatör bir fotoğrafçıdır.","e2":"Amateur sports.","e2t":"Amatör sporlar."},{"w":"amateurish","tr":"amatörce / acemice","te":"Adjective","tt":"Sıfat","de":"Done in an unskillful or inept way","dt":"Beceriksizce veya profesyonellikten uzak yapılmış","e1":"The performance was rather amateurish.","e1t":"Gösteri oldukça amatörceydi.","e2":"Amateurish mistake.","e2t":"Acemice hata."},{"w":"ambiguity","tr":"belirsizlik / muğlaklık","te":"Noun","tt":"İsim","de":"The state of having more than one possible meaning","dt":"Birden fazla olası anlama sahip olma durumu","e1":"There is some ambiguity in the law.","e1t":"Yasada bazı belirsizlikler (muğlaklıklar) var.","e2":"Avoid ambiguity in your writing.","e2t":"Yazınızda belirsizlikten kaçının."},{"w":"ambivalent","tr":"kararsız / iki demli","te":"Adjective","tt":"Sıfat","de":"Having mixed feelings about something","dt":"Bir şey hakkında karışık duygulara sahip olma","e1":"He has an ambivalent attitude towards his job.","e1t":"İşine karşı kararsız (karışık) bir tutumu var.","e2":"Ambivalent feelings.","e2t":"Kararsız duygular."},{"w":"ambush","tr":"pusu / pusuya düşürmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A surprise attack from a concealed position","dt":"Gizli bir konumdan yapılan sürpriz saldırı","e1":"The soldiers were caught in an ambush.","e1t":"Askerler pusuya düşürüldü.","e2":"Lead into an ambush.","e2t":"Pusuya düşürmek."},{"w":"amend","tr":"düzeltmek / değiştirmek (yasa vb.)","te":"Verb","tt":"Fiil","de":"To change the words of a law or document","dt":"Bir yasanın veya belgenin kelimelerini değiştirmek","e1":"The law was amended to include new regulations.","e1t":"Yasa, yeni düzenlemeleri içerecek şekilde değiştirildi (düzeltildi).","e2":"To amend the constitution.","e2t":"Anayasayı düzeltmek."},{"w":"amiable","tr":"dostça / cana yakın","te":"Adjective","tt":"Sıfat","de":"Friendly and pleasant","dt":"Dost canlısı ve hoş","e1":"An amiable young man.","e1t":"Cana yakın genç bir adam.","e2":"They reached an amiable agreement.","e2t":"Dostça bir anlaşmaya vardılar."},{"w":"ample","tr":"bol / kafi / geniş","te":"Adjective","tt":"Sıfat","de":"More than enough","dt":"Yeterinden fazla","e1":"There is ample evidence to prove his guilt.","e1t":"Suçunu kanıtlamak için bolca delil var.","e2":"Ample parking space.","e2t":"Geniş (yeterli) park alanı."},{"w":"analytical","tr":"analitik / çözümleyici","te":"Adjective","tt":"Sıfat","de":"Examining something carefully to understand it","dt":"Bir şeyi anlamak için dikkatle inceleyen","e1":"Analytical thinking.","e1t":"Analitik düşünme.","e2":"He has a very analytical mind.","e2t":"Çok analitik (çözümleyici) bir zihni var."},{"w":"ancestry","tr":"soy / ecdat","te":"Noun","tt":"İsim","de":"One's family or ethnic descent","dt":"Birinin ailesi veya etnik kökeni","e1":"He is proud of his noble ancestry.","e1t":"Soylu ecdadıyla gurur duyuyor.","e2":"Common ancestry.","e2t":"Ortak soy."},{"w":"animate","tr":"canlandırmak / canlı","te":"Verb/Adjective","tt":"To make something look like it is moving","de":"Bir şeye hareket ediyormuş gibi görünüm vermek","dt":"To animate a cartoon character.","e1":"Bir çizgi film karakterini canlandırmak.","e1t":"Animate objects (living things).","e2":"Canlı nesneler.","e2t":""},{"w":"anonymous","tr":"anonim / isimsiz","te":"Adjective","tt":"Sıfat","de":"Made or done by someone whose name is not known","dt":"İsmi bilinmeyen biri tarafından yapılmış","e1":"An anonymous letter.","e1t":"İsimsiz bir mektup.","e2":"The donor wishes to remain anonymous.","e2t":"Bağışçı isimsiz kalmak istiyor."},{"w":"antelope","tr":"antilop","te":"Noun","tt":"İsim","de":"A swift","dt":"running deer","e1":"like animal","e1t":"Hızlı koşan, geyiğe benzeyen hayvan","e2":"We saw a herd of antelopes.","e2t":"Bir antilop sürüsü gördük."},{"w":"anti","tr":"virus","te":"antivirüs","tt":"Adjective/Noun","de":"Sıfat/İsim","dt":"Software designed to detect and destroy computer viruses","e1":"Bilgisayar virüslerini yok etmek için tasarlanmış yazılım","e1t":"Make sure your anti","e2":"virus is updated.","e2t":"Antivirüs yazılımınızın güncel olduğundan emin olun."},{"w":"anticlockwise","tr":"saat yönünün tersine","te":"Adverb/Adjective","tt":"In the opposite direction to the movement of clock hands","de":"Saat yelkovanının hareketinin tersi yönünde","dt":"Turn the key anticlockwise to open it.","e1":"Açmak için anahtarı saat yönünün tersine çevir.","e1t":"Rotate anticlockwise.","e2":"Sola (saat yönü tersine) döndürmek.","e2t":""},{"w":"antique","tr":"antika","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something made in an earlier period that is valuable","dt":"Eski bir dönemde yapılmış değerli şey","e1":"Antique furniture.","e1t":"Antika mobilya.","e2":"This watch is a valuable antique.","e2t":"Bu saat değerli bir antikadır."},{"w":"appliance","tr":"cihaz / alet","te":"Noun","tt":"İsim","de":"A device or piece of equipment for a specific task","dt":"Belirli bir iş için kullanılan cihaz","e1":"Modern kitchen appliances save time.","e1t":"Modern mutfak cihazları zaman kazandırır.","e2":"Household appliances.","e2t":"Ev aletleri."},{"w":"applicable","tr":"uygulanabilir / ilgili","te":"Adjective","tt":"Sıfat","de":"Affecting or relating to someone or something","dt":"Birini veya bir şeyi etkileyen veya onunla ilgili olan","e1":"These rules are applicable to everyone.","e1t":"Bu kurallar herkes için uygulanabilir (geçerli).","e2":"The new law is not applicable in this case.","e2t":"Yeni yasa bu durumda uygulanabilir değil."},{"w":"appointee","tr":"atanan kişi","te":"Noun","tt":"İsim","de":"A person who is appointed to a job or office","dt":"Bir işe veya makama atanan kişi","e1":"The new appointee will start next week.","e1t":"Yeni atanan kişi haftaya başlayacak.","e2":"Political appointee.","e2t":"Siyasi atanan."},{"w":"appraisal","tr":"değerlendirme / paha biçme","te":"Noun","tt":"İsim","de":"The act of judging the value or quality of something","dt":"Bir şeyin değerini veya kalitesini yargılama eylemi","e1":"Performance appraisal.","e1t":"Performans değerlendirmesi.","e2":"A formal appraisal of the building.","e2t":"Binanın resmi bir değerlemesi."},{"w":"approvable","tr":"onaylanabilir","te":"Adjective","tt":"Sıfat","de":"Worthy of being approved","dt":"Onaylanmaya değer, kabul edilebilir","e1":"This is an approvable request.","e1t":"Bu onaylanabilir bir taleptir.","e2":"Approvable plan.","e2t":"Onaylanabilir plan."},{"w":"apricot","tr":"kayısı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A juicy, soft orange","dt":"yellow fruit","e1":"Sulu, turuncu","e1t":"sarı renkli meyve","e2":"I love dried apricots.","e2t":"Kuru kayısıyı severim."},{"w":"aquarium","tr":"akvaryum","te":"Noun","tt":"İsim","de":"A transparent tank of water in which fish are kept","dt":"Balıkların tutulduğu şeffaf su tankı","e1":"We visited the city aquarium.","e1t":"Şehir akvaryumunu ziyaret ettik.","e2":"Tropical aquarium.","e2t":"Tropikal akvaryum."},{"w":"arbitrary","tr":"keyfi / rastgele","te":"Adjective","tt":"Sıfat","de":"Based on chance rather than being planned","dt":"Planlanmış olmaktan ziyade şansa dayalı","e1":"An arbitrary decision.","e1t":"Keyfi bir karar.","e2":"Arbitrary rules.","e2t":"Keyfi kurallar."},{"w":"arc","tr":"yay / kavis","te":"Noun/Verb","tt":"İsim/Fiil","de":"A curved shape or line","dt":"Kavisli şekil veya çizgi","e1":"The rainbow forms a beautiful arc.","e1t":"Gökkuşağı güzel bir yay oluşturur.","e2":"An arc of light.","e2t":"Bir ışık kavisi."},{"w":"archery","tr":"okçuluk","te":"Noun","tt":"İsim","de":"The sport or skill of shooting with a bow and arrows","dt":"Yay ve okla atış yapma sporu veya becerisi","e1":"She is practicing archery for the competition.","e1t":"Yarışma için okçuluk antrenmanı yapıyor.","e2":"Target archery.","e2t":"Hedef okçuluğu."},{"w":"architectural","tr":"mimari","te":"Adjective","tt":"Sıfat","de":"Relating to architecture","dt":"Mimari ile ilgili","e1":"Architectural style.","e1t":"Mimari tarz.","e2":"Architectural heritage.","e2t":"Mimari miras."},{"w":"archive","tr":"arşiv / arşivlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A collection of historical documents or to store them","dt":"Tarihi belgeler koleksiyonu veya bunları saklamak","e1":"Historical archives.","e1t":"Tarihi arşivler.","e2":"Please archive these emails.","e2t":"Lütfen bu e"},{"w":"ardent","tr":"tutkulu / ateşli","te":"Adjective","tt":"Sıfat","de":"Showing strong feelings","dt":"Güçlü duygular gösteren","e1":"An ardent supporter of the team.","e1t":"Takımın tutkulu bir destekçisi.","e2":"Ardent love.","e2t":"Ateşli aşk."},{"w":"arena","tr":"arena / alan","te":"Noun","tt":"İsim","de":"A place for sports or public events; or a sphere of activity","dt":"Spor veya etkinlik alanı; veya faaliyet alanı","e1":"A political arena.","e1t":"Siyasi bir arena (alan).","e2":"The basketball arena was full.","e2t":"Basketbol arenası doluydu."},{"w":"arguably","tr":"tartışılabilir şekilde / muhtemelen","te":"Adverb","tt":"Zarf","de":"Used when stating an opinion that may be disagreed with","dt":"Katılınmayabilecek bir fikir belirtirken kullanılır","e1":"He is arguably the best player in the world.","e1t":"O, tartışmasız (muhtemelen) dünyanın en iyi oyuncusudur.","e2":"This is arguably her best book.","e2t":"Bu, muhtemelen onun en iyi kitabıdır."},{"w":"aroma","tr":"aroma / hoş koku","te":"Noun","tt":"İsim","de":"A distinctive, typically pleasant smell","dt":"Kendine has, genellikle hoş koku","e1":"I love the aroma of fresh coffee.","e1t":"Taze kahvenin kokusuna bayılırım.","e2":"Spicy aroma.","e2t":"Baharatlı aroma."},{"w":"arouse","tr":"uyandırmak / harekete geçirmek","te":"Verb","tt":"Fiil","de":"To evoke or awaken a feeling or response","dt":"Bir duyguyu veya tepkiyi tetiklemek","e1":"His behavior aroused suspicion.","e1t":"Davranışı şüphe uyandırdı.","e2":"Arouse interest.","e2t":"İlgi uyandırmak."},{"w":"articulate","tr":"açık ifade etmek / telaffuz etmek / kendini iyi ifade eden","te":"Verb/Adjective","tt":"To express ideas clearly in words","de":"Fikirleri kelimelerle net bir şekilde ifade etmek","dt":"He struggled to articulate his feelings.","e1":"Duygularını açıkça ifade etmekte zorlandı.","e1t":"She is an articulate speaker.","e2":"O, kendini iyi ifade eden (hitabeti güçlü) bir konuşmacıdır.","e2t":""},{"w":"artifact","tr":"eser (tarihi) / yapay olgu","te":"Noun","tt":"İsim","de":"An object made by a human being, typically of historical interest","dt":"İnsan yapımı, genellikle tarihi önemi olan nesne","e1":"Ancient Egyptian artifacts.","e1t":"Antik Mısır eserleri.","e2":"Cultural artifacts.","e2t":"Kültürel eserler."},{"w":"ascent","tr":"çıkış / yükseliş","te":"Noun","tt":"İsim","de":"A climb or walk to the summit of a mountain","dt":"Bir dağın zirvesine tırmanış veya yürüyüş","e1":"The ascent of Mount Everest is difficult.","e1t":"Everest Dağı'nın tırmanışı (çıkışı) zordur.","e2":"Rapid ascent.","e2t":"Hızlı yükseliş."},{"w":"ascertain","tr":"doğrulamak / belirlemek / aslını öğrenmek","te":"Verb","tt":"Fiil","de":"To find out for certain","dt":"Kesin olarak öğrenmek","e1":"The police are trying to ascertain the cause of the fire.","e1t":"Polis yangının nedenini belirlemeye (aslını öğrenmeye) çalışıyor.","e2":"Please ascertain whether the flight is on time.","e2t":"Lütfen uçuşun zamanında olup olmadığını doğrulayın."},{"w":"ashore","tr":"kıyıya / karaya","te":"Adverb","tt":"Zarf","de":"To or on the shore or land from the water","dt":"Sudan karaya veya kıyıya doğru","e1":"The sailors finally came ashore.","e1t":"Denizciler sonunda karaya çıktı.","e2":"Wash ashore.","e2t":"Kıyıya vurmak."},{"w":"asphalt","tr":"asfalt","te":"Noun/Verb","tt":"İsim/Fiil","de":"A dark bituminous substance used for surfacing roads","dt":"Yol yapımında kullanılan koyu bitümlü madde","e1":"The road is covered with fresh asphalt.","e1t":"Yol taze asfaltla kaplı.","e2":"Asphalt road.","e2t":"Asfalt yol."},{"w":"aspiration","tr":"arzu / istek / soluma","te":"Noun","tt":"İsim","de":"Something that you hope to achieve","dt":"Başarmayı umduğunuz şey","e1":"High aspirations.","e1t":"Yüksek idealler (arzular).","e2":"Career aspirations.","e2t":"Kariyer hedefleri (istekleri)."},{"w":"aspire","tr":"arzu etmek / can atmak","te":"Verb","tt":"Fiil","de":"To have a strong wish to achieve something","dt":"Bir şeyi başarmak için güçlü bir arzu duymak","e1":"He aspires to become a famous scientist.","e1t":"Ünlü bir bilim insanı olmayı arzu ediyor.","e2":"She aspired to a career in music.","e2t":"Müzik alanında bir kariyere can atıyordu."},{"w":"aspirin","tr":"aspirin","te":"Noun","tt":"İsim","de":"A drug used to relieve pain and reduce fever","dt":"Ağrı kesici ve ateş düşürücü ilaç","e1":"Take an aspirin for your headache.","e1t":"Baş ağrın için bir aspirin al.","e2":"Aspirin tablet.","e2t":"Aspirin tableti."},{"w":"assassin","tr":"suikastçı","te":"Noun","tt":"İsim","de":"A person who murders an important person","dt":"Önemli bir kişiyi öldüren (suikast düzenleyen) kişi","e1":"The assassin was caught by the police.","e1t":"Suikastçı polis tarafından yakalandı.","e2":"Hired assassin.","e2t":"Kiralık katil."},{"w":"assault","tr":"saldırı / saldırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A physical attack","dt":"Fiziksel saldırı","e1":"He was charged with sexual assault.","e1t":"Cinsel saldırıyla suçlandı.","e2":"Armed assault.","e2t":"Silahlı saldırı."},{"w":"assemble","tr":"toplamak / birleştirmek / monte etmek","te":"Verb","tt":"Fiil","de":"To bring together or to build something by joining parts","dt":"Bir araya getirmek veya parçaları birleştirerek inşa etmek","e1":"The students assembled in the hall.","e1t":"Öğrenciler salonda toplandı.","e2":"The furniture is easy to assemble.","e2t":"Mobilyanın montajı (birleştirilmesi) kolaydır."},{"w":"assembly","tr":"montaj / meclis / toplantı","te":"Noun","tt":"İsim","de":"A group of people gathered together; or the action of fitting parts","dt":"Toplanan insan grubu; veya parçaların birleştirilmesi","e1":"The school assembly starts at 9.","e1t":"Okul toplantısı 9'da başlıyor.","e2":"Assembly line.","e2t":"Montaj hattı."},{"w":"assert","tr":"iddia etmek / ileri sürmek / savunmak","te":"Verb","tt":"Fiil","de":"To state clearly that something is true","dt":"Bir şeyin doğru olduğunu net bir şekilde belirtmek","e1":"He asserted his innocence.","e1t":"Masumiyetini iddia etti.","e2":"She continues to assert that she was right.","e2t":"Haklı olduğunu ileri sürmeye devam ediyor."},{"w":"assessable","tr":"değerlendirilebilir","te":"Adjective","tt":"Sıfat","de":"Capable of being assessed","dt":"Değerlendirilebilir veya vergilendirilebilir durumda olan","e1":"The damage is easily assessable.","e1t":"Hasar kolayca değerlendirilebilir.","e2":"Assessable income.","e2t":"Vergilendirilebilir gelir."},{"w":"assignable","tr":"atanabilir / devredilebilir","te":"Adjective","tt":"Sıfat","de":"Capable of being assigned","dt":"Atanabilir veya birine devredilebilir olan","e1":"These tasks are assignable to junior staff.","e1t":"Bu görevler alt kademe personele atanabilir.","e2":"Assignable rights.","e2t":"Devredilebilir haklar."},{"w":"assimilate","tr":"özümsemek / asimile etmek / benzeşmek","te":"Verb","tt":"Fiil","de":"To absorb fully; to become part of a group","dt":"Tamamen emmek; bir grubun parçası haline gelmek","e1":"It takes time to assimilate new ideas.","e1t":"Yeni fikirleri özümsemek zaman alır.","e2":"The immigrants were quickly assimilated into the local culture.","e2t":"Göçmenler yerel kültüre hızla asimile oldular (uyum sağladılar)."},{"w":"assortment","tr":"çeşitlilik / karışım","te":"Noun","tt":"İsim","de":"A miscellaneous collection of things","dt":"Çeşitli şeylerin bir araya geldiği koleksiyon","e1":"They sell a wide assortment of tools.","e1t":"Çok çeşitli araç gereç satıyorlar.","e2":"Random assortment.","e2t":"Rastgele karışım."},{"w":"assumption","tr":"varsayım / üstlenme","te":"Noun","tt":"İsim","de":"Something that you accept as true without proof","dt":"Kanıt olmadan doğru kabul ettiğiniz şey","e1":"We are working on the assumption that the project will be approved.","e1t":"Projenin onaylanacağı varsayımıyla çalışıyoruz.","e2":"A false assumption.","e2t":"Yanlış bir varsayım."},{"w":"assurance","tr":"güvence / özgüven / sigorta (UK)","te":"Noun","tt":"İsim","de":"A promise that something is true; or self","dt":"confidence","e1":"Bir şeyin doğru olduğuna dair söz; veya özgüven","e1t":"Quality assurance.","e2":"Kalite güvencesi.","e2t":"He spoke with great assurance."},{"w":"astonish","tr":"şaşırtmak / hayrete düşürmek","te":"Verb","tt":"Fiil","de":"To surprise someone very much","dt":"Birini çok fazla şaşırtmak","e1":"Her success astonished everyone.","e1t":"Onun başarısı herkesi şaşırttı (hayrete düşürdü).","e2":"I was astonished by the news.","e2t":"Haberlere hayret ettim."},{"w":"asylum","tr":"sığınma / barınak / akıl hastanesi (eski)","te":"Noun","tt":"İsim","de":"Protection given by a government to a refugee","dt":"Bir hükümetin bir mülteciye verdiği koruma","e1":"Political asylum.","e1t":"Siyasi sığınma.","e2":"To seek asylum.","e2t":"Sığınma talebinde bulunmak."},{"w":"attain","tr":"elde etmek / ulaşmak / başarmak","te":"Verb","tt":"Fiil","de":"To achieve something difficult","dt":"Zor bir şeyi başarmak (ona ulaşmak)","e1":"He finally attained his goal of becoming a doctor.","e1t":"Sonunda doktor olma hedefine ulaştı.","e2":"To attain a high level of proficiency.","e2t":"Yüksek bir yeterlilik seviyesine ulaşmak."},{"w":"attentive","tr":"dikkatli / özenli","te":"Adjective","tt":"Sıfat","de":"Listening carefully or paying close attention","dt":"Dikkatle dinleyen veya yakından ilgilenen","e1":"An attentive audience.","e1t":"Dikkatli bir dinleyici kitlesi.","e2":"She is very attentive to her students' needs.","e2t":"Öğrencilerinin ihtiyaçlarına karşı çok özenlidir."},{"w":"attest","tr":"kanıtlamak / doğrulamak / tanıklık etmek","te":"Verb","tt":"Fiil","de":"To show or prove that something is true","dt":"Bir şeyin doğru olduğunu göstermek veya kanıtlamak","e1":"His success attests to his hard work.","e1t":"Başarısı, sıkı çalışmasını kanıtlıyor.","e2":"As a witness, I can attest to his innocence.","e2t":"Bir tanık olarak, onun masumiyetine tanıklık edebilirim."},{"w":"attributable","tr":"","te":"den kaynaklanabilir /","tt":"e bağlanabilir","de":"Adjective","dt":"Sıfat","e1":"Caused by a particular thing","e1t":"Belirli bir şeyden kaynaklanan","e2":"The accident was attributable to human error.","e2t":"Kaza, insan hatasına bağlanabilirdi (kaynaklıydı)."},{"w":"audit","tr":"denetim / denetlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official examination of accounts or records","dt":"Kayıtların veya hesapların resmi incelemesi","e1":"Internal audit.","e1t":"İç denetim.","e2":"The company is undergoing an annual audit.","e2t":"Şirket yıllık bir denetimden geçiyor."},{"w":"authentic","tr":"gerçek / otantik / özgün","te":"Adjective","tt":"Sıfat","de":"Real and true, not a copy","dt":"Gerçek ve doğru, kopya olmayan","e1":"An authentic Turkish breakfast.","e1t":"Gerçek bir Türk kahvaltısı.","e2":"This is an authentic document.","e2t":"Bu özgün (gerçek) bir belgedir."},{"w":"authorize","tr":"yetkilendirmek / izin vermek","te":"Verb","tt":"Fiil","de":"To give official permission","dt":"Resmi izin vermek","e1":"The manager authorized the payment.","e1t":"Müdür ödemeyi yetkilendirdi (onayladı).","e2":"An authorized dealer.","e2t":"Yetkili satıcı (bayi)."},{"w":"automate","tr":"otomatikleştirmek","te":"Verb","tt":"Fiil","de":"To use machines to do work instead of people","dt":"İnsanlar yerine makineleri kullanmak","e1":"We are trying to automate the factory.","e1t":"Fabrikayı otomatikleştirmeye çalışıyoruz.","e2":"Automated systems.","e2t":"Otomatikleştirilmiş sistemler."},{"w":"autonomy","tr":"özerklik / otonomi","te":"Noun","tt":"İsim","de":"The right of an organization or country to govern itself","dt":"Bir kuruluşun veya ülkenin kendi kendini yönetme hakkı","e1":"Local governments need more autonomy.","e1t":"Yerel yönetimlerin daha fazla özerkliğe ihtiyacı var.","e2":"Academic autonomy.","e2t":"Akademik özerklik."},{"w":"auxiliary","tr":"yardımcı / destekleyici","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Giving help or support to the main group","dt":"Ana gruba yardım veya destek veren","e1":"Auxiliary verb (grammar).","e1t":"Yardımcı fiil.","e2":"An auxiliary power supply.","e2t":"Yardımcı (yedek) güç kaynağı."},{"w":"availability","tr":"kullanılabilirlik / mevcut olma","te":"Noun","tt":"İsim","de":"The state of being able to be used or obtained","dt":"Kullanılabilir veya elde edilebilir olma durumu","e1":"Please check the availability of the rooms.","e1t":"Lütfen odaların müsaitlik (mevcut olma) durumunu kontrol edin.","e2":"Data availability.","e2t":"Veri kullanılabilirliği."},{"w":"avert","tr":"önlemek / başka yöne çevirmek","te":"Verb","tt":"Fiil","de":"To prevent something bad from happening","dt":"Kötü bir şeyin olmasını engellemek","e1":"A disaster was narrowly averted.","e1t":"Bir felaket kıl payı önlendi.","e2":"He averted his eyes from the accident.","e2t":"Gözlerini kazadan başka yöne çevirdi."},{"w":"avid","tr":"hevesli / tutkulu / hırslı","te":"Adjective","tt":"Sıfat","de":"Extremely eager or interested","dt":"Son derece istekli veya ilgili","e1":"An avid reader.","e1t":"Hevesli bir okuyucu.","e2":"He is an avid fan of scuba diving.","e2t":"O, tüplü dalışın tutkulu bir hayranıdır."},{"w":"bachelor","tr":"bekâr erkek / lisans mezunu","te":"Noun","tt":"İsim","de":"An unmarried man; or a person with a first university degree","dt":"Evlenmemiş erkek; veya üniversite mezunu kişi","e1":"He is a confirmed bachelor.","e1t":"O, müzmin bir bekârdır.","e2":"Bachelor of Science (BSc).","e2t":"Fen Bilimleri Lisansı."},{"w":"backdrop","tr":"arka plan / dekor","te":"Noun","tt":"İsim","de":"The general situation in which something happens; or a painted cloth","dt":"Bir şeyin gerçekleştiği genel durum; veya dekor fonu","e1":"The mountains provided a beautiful backdrop.","e1t":"Dağlar güzel bir arka plan oluşturdu.","e2":"Against a backdrop of economic crisis.","e2t":"Ekonomik kriz fonunda (arka planında)."},{"w":"badge","tr":"rozet / kimlik kartı / simge","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of metal or plastic with a design","dt":"Tasarımı olan küçük metal veya plastik parça","e1":"Police badge.","e1t":"Polis rozeti.","e2":"A badge of courage.","e2t":"Cesaret simgesi."},{"w":"baffle","tr":"şaşırtmak / kafasını karıştırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To confuse someone completely","dt":"Birinin kafasını tamamen karıştırmak","e1":"The puzzle completely baffled me.","e1t":"Bulmaca kafamı tamamen karıştırdı.","e2":"Scientists are baffled by the results.","e2t":"Bilim insanları sonuçlar karşısında şaşkın (çaresiz)."},{"w":"bankrupt","tr":"iflas etmiş / batık","te":"Adjective/Noun/Verb","tt":"Unable to pay what you owe","de":"Borçlarını ödeyemeyen","dt":"The company went bankrupt.","e1":"Şirket iflas etti.","e1t":"Morally bankrupt.","e2":"Ahlaken çökmüş.","e2t":""},{"w":"bare","tr":"çıplak / yalın / boş","te":"Adjective/Verb","tt":"Not covered by anything; simple","de":"Hiçbir şeyle örtülmemiş; basit/yalın","dt":"Bare feet.","e1":"Çıplak ayaklar.","e1t":"The bare necessities of life.","e2":"Hayatın en temel (yalın) ihtiyaçları.","e2t":""},{"w":"bargain","tr":"pazarlık / kelepir / ucuz eşya","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something on sale at a lower price than its true value","dt":"Değerinden ucuza satılan şey","e1":"This dress was a real bargain.","e1t":"Bu elbise gerçek bir kelepirdi (çok ucuzdu).","e2":"We bargained with the seller.","e2t":"Satıcıyla pazarlık yaptık."},{"w":"bashful","tr":"utangaç / çekingen","te":"Adjective","tt":"Sıfat","de":"Shy and easily embarrassed","dt":"Utangaç ve kolayca utanan","e1":"He gave her a bashful smile.","e1t":"Ona utangaç bir gülümseme verdi.","e2":"Don't be bashful, come in!","e2t":"Çekingen olma, içeri gir!"},{"w":"beloved","tr":"sevilen / sevgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Loved very much","dt":"Çok sevilen","e1":"My beloved wife.","e1t":"Sevgili eşim.","e2":"He is beloved by all his students.","e2t":"Tüm öğrencileri tarafından sevilir."},{"w":"beneficial","tr":"faydalı / yararlı","te":"Adjective","tt":"Sıfat","de":"Helpful or useful","dt":"Yardımcı veya yararlı","e1":"Regular exercise is beneficial to health.","e1t":"Düzenli egzersiz sağlık için faydalıdır.","e2":"A beneficial effect.","e2t":"Yararlı bir etki."},{"w":"benevolent","tr":"hayırsever / yardımsever","te":"Adjective","tt":"Sıfat","de":"Kind and helpful","dt":"Nazik ve yardımsever","e1":"A benevolent organization.","e1t":"Hayırsever bir kuruluş.","e2":"A benevolent smile.","e2t":"Yardımsever (iyicil) bir gülümseme."},{"w":"betray","tr":"ihanet etmek / ele vermek / açığa vurmak","te":"Verb","tt":"Fiil","de":"To be disloyal to someone; or to reveal a secret","dt":"Birine sadakatsizlik etmek; veya bir sırrı ifşa etmek","e1":"He betrayed his country.","e1t":"Ülkesine ihanet etti.","e2":"Her face betrayed her nervousness.","e2t":"Yüzü gerginliğini ele verdi (açığa vurdu)."},{"w":"bewilder","tr":"afallatmak / şaşırtmak","te":"Verb","tt":"Fiil","de":"To confuse someone very much","dt":"Birinin kafasını çok karıştırmak","e1":"I was bewildered by the complex instructions.","e1t":"Karmaşık talimatlar karşısında afalladım.","e2":"A bewildering variety of choices.","e2t":"Şaşırtıcı (kafa karıştırıcı) çeşitlilikte seçenekler."},{"w":"bilateral","tr":"iki taraflı","te":"Adjective","tt":"Sıfat","de":"Involving two groups or countries","dt":"İki grubu veya ülkeyi kapsayan","e1":"Bilateral agreement.","e1t":"İki taraflı anlaşma.","e2":"Bilateral relations.","e2t":"İki taraflı ilişkiler."},{"w":"bizarre","tr":"tuhaf / garip / acayip","te":"Adjective","tt":"Sıfat","de":"Very strange and unusual","dt":"Çok garip ve alışılmadık","e1":"A bizarre coincidence.","e1t":"Tuhaf bir tesadüf.","e2":"He has a bizarre sense of humor.","e2t":"Garip bir mizah anlayışı var."},{"w":"bleak","tr":"kasvetli / umutsuz / çıplak (arazi)","te":"Adjective","tt":"Sıfat","de":"Cold and empty; or without hope","dt":"Soğuk ve boş; veya umutsuz","e1":"The future looks bleak.","e1t":"Gelecek umutsuz (kasvetli) görünüyor.","e2":"A bleak landscape.","e2t":"Kasvetli (çorak) bir manzara."},{"w":"blueprint","tr":"taslak / mavi ozalit / plan","te":"Noun/Verb","tt":"İsim/Fiil","de":"A detailed plan or design","dt":"Detaylı plan veya tasarım","e1":"A blueprint for the new school building.","e1t":"Yeni okul binası için bir taslak (plan).","e2":"A blueprint for success.","e2t":"Başarı için bir yol haritası (plan)."},{"w":"booth","tr":"kabin / gişe / küçük dükkan","te":"Noun","tt":"İsim","de":"A small small space for one person","dt":"Bir kişilik küçük alan","e1":"Voting booth.","e1t":"Oy verme kabini.","e2":"Telephone booth.","e2t":"Telefon kulübesi."},{"w":"boredom","tr":"can sıkıntısı","te":"Noun","tt":"İsim","de":"The state of feeling bored","dt":"Sıkılmış olma durumu","e1":"He died of boredom.","e1t":"Can sıkıntısından öldü.","e2":"To relieve the boredom of a long journey.","e2t":"Uzun bir yolculuğun can sıkıntısını gidermek."},{"w":"bounce","tr":"zıplamak / geri dönmek (e","te":"posta vb.)","tt":"Verb/Noun","de":"Fiil/İsim","dt":"To move up and down or to return","e1":"Yukarı aşağı hareket etmek veya geri dönmek","e1t":"The ball bounced off the wall.","e2":"Top duvardan sekti (zıpladı).","e2t":"The email bounced back."},{"w":"bow","tr":"eğilmek / yay / pruva","te":"Verb/Noun","tt":"Fiil/İsim","de":"To bend the head or body forward","dt":"Başı veya vücudu öne eğmek","e1":"He bowed to the audience.","e1t":"Dinleyicilere doğru eğildi (selam verdi).","e2":"Violin bow.","e2t":"Keman yayı."},{"w":"brace","tr":"desteklemek / hazırlamak / diş teli","te":"Verb/Noun","tt":"Fiil/İsim","de":"To support or to prepare for something difficult","dt":"Desteklemek veya zor bir şeye hazırlanmak","e1":"Brace yourself for bad news.","e1t":"Kendini kötü habere hazırla.","e2":"He wears a neck brace.","e2t":"Boyunluk (destek) takıyor."},{"w":"brag","tr":"böbürlenmek / övünmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak too proudly about what you have done","dt":"Yaptıkların hakkında fazla gururlu konuşmak","e1":"Stop bragging about your car.","e1t":"Araban hakkında böbürlenmeyi bırak.","e2":"He is always bragging.","e2t":"O her zaman övünür."},{"w":"breakthrough","tr":"büyük buluş / atılım / ilerleme","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An important discovery or development","dt":"Önemli bir keşif veya gelişme","e1":"A major breakthrough in cancer research.","e1t":"Kanser araştırmalarında büyük bir buluş (atılım).","e2":"A breakthrough technology.","e2t":"Çığır açan bir teknoloji."},{"w":"breed","tr":"yetiştirmek (hayvan) / tür / cins","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep animals for the purpose of producing young","dt":"Yavru üretmek amacıyla hayvan bakmak","e1":"He breeds Labradors.","e1t":"Labrador (cinsi köpek) yetiştiriyor.","e2":"A rare breed of sheep.","e2t":"Nadir bir koyun cinsi."},{"w":"breeze","tr":"esinti / hafif rüzgar / çocuk oyuncağı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A light wind; or something easy to do","dt":"Hafif rüzgar; veya yapması kolay şey","e1":"A sea breeze.","e1t":"Deniz esintisi.","e2":"The exam was a breeze.","e2t":"Sınav çocuk oyuncağıydı (çok kolaydı)."},{"w":"brew","tr":"demlemek / (fırtına vb.) kopmak üzere olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make tea, coffee, or beer","dt":"Çay, kahve veya bira yapmak","e1":"Let the tea brew for five minutes.","e1t":"Çayın beş dakika demlenmesine izin ver.","e2":"Trouble is brewing.","e2t":"Sorun kapıda (demleniyor/başlamak üzere)."},{"w":"bribe","tr":"rüşvet / rüşvet vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money given to someone to make them do something","dt":"Birine bir şey yaptırmak için verilen para","e1":"He accepted a bribe.","e1t":"Rüşvet kabul etti.","e2":"They tried to bribe the official.","e2t":"Memura rüşvet vermeye çalıştılar."},{"w":"brisk","tr":"canlı / hareketli / sert (hava)","te":"Adjective/Verb","tt":"Quick and energetic","de":"Hızlı ve enerjik","dt":"A brisk walk.","e1":"Tempolu (canlı) bir yürüyüş.","e1t":"Business is brisk.","e2":"İşler hareketli.","e2t":""},{"w":"brittle","tr":"kırılgan / gevrek","te":"Adjective","tt":"Sıfat","de":"Hard but easily broken","dt":"Sert ama kolayca kırılan","e1":"Brittle bones.","e1t":"Kırılgan kemikler.","e2":"Dry leaves are very brittle.","e2t":"Kuru yapraklar çok kırılgandır."},{"w":"brochure","tr":"broşür","te":"Noun","tt":"İsim","de":"A small magazine containing information about something","dt":"Bir şey hakkında bilgi içeren küçük dergi","e1":"A holiday brochure.","e1t":"Tatil broşürü.","e2":"We handed out brochures.","e2t":"Broşürler dağıttık."},{"w":"bruise","tr":"morartı / ezik / incitmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A purple mark on the skin caused by a hit","dt":"Vuruş kaynaklı ciltteki mor leke","e1":"I have a bruise on my arm.","e1t":"Kolumda bir morartı var.","e2":"Bruised fruit.","e2t":"Ezilmiş meyve."},{"w":"brutal","tr":"acımasız / zalimce / sert","te":"Adjective","tt":"Sıfat","de":"Cruel, violent, and completely without feelings","dt":"Zalim, şiddetli ve tamamen duygusuz","e1":"A brutal murder.","e1t":"Acımasızca bir cinayet.","e2":"The truth can be brutal.","e2t":"Gerçek acımasız olabilir."},{"w":"bubble","tr":"kabarcık / baloncuk","te":"Noun/Verb","tt":"İsim/Fiil","de":"A ball of air or gas in a liquid","dt":"Sıvı içindeki hava veya gaz topu","e1":"Soap bubbles.","e1t":"Sabun baloncukları.","e2":"The water began to bubble.","e2t":"Su fıkırdamaya (kabarcık çıkarmaya) başladı."},{"w":"buddy","tr":"dost / kanka / arkadaş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A friend","dt":"Arkadaş","e1":"We have been buddies since childhood.","e1t":"Çocukluktan beri kankayız (dostuz).","e2":"Study buddy.","e2t":"Çalışma arkadaşı."},{"w":"buffer","tr":"tampon / koruyucu bölge","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that protects against a shock or change","dt":"Şoka veya değişime karşı koruyan şey","e1":"A buffer state (between two countries).","e1t":"Tampon bölge/devlet.","e2":"The garden acts as a buffer against noise.","e2t":"Bahçe gürültüye karşı bir tampon görevi görüyor."},{"w":"bulky","tr":"hantal / büyük / yer kaplayan","te":"Adjective","tt":"Sıfat","de":"Large and difficult to carry","dt":"Büyük ve taşıması zor","e1":"Bulky items like furniture.","e1t":"Mobilya gibi hantal eşyalar.","e2":"A bulky sweater.","e2t":"Kalın (hantal) bir kazak."},{"w":"bully","tr":"zorba / kabadayılık yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Someone who hurts or frightens weaker people","dt":"Zayıf insanları inciten veya korkutan kişi","e1":"He was a school bully.","e1t":"O bir okul zorbasıydı.","e2":"Stop bullying me!","e2t":"Bana zorbalık yapmayı (üzerime gelmeyi) bırak!"},{"w":"bump","tr":"çarpmak / toslamak / tümsek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit something by accident; or a small raised area","dt":"Kazara bir şeye vurmak; veya küçük yükselti","e1":"I bumped my head against the shelf.","e1t":"Kafamı rafa çarptım.","e2":"Speed bump.","e2t":"Hız tümseği (kasis)."},{"w":"bundle","tr":"paket / deste / çıkın","te":"Noun/Verb","tt":"İsim/Fiil","de":"A number of things tied or wrapped together","dt":"Birlikte bağlanmış veya sarılmış bir dizi şey","e1":"A bundle of letters.","e1t":"Bir deste (paket) mektup.","e2":"They bundled the newspapers for recycling.","e2t":"Gazeteleri geri dönüşüm için paketlediler."},{"w":"bureau","tr":"ofis / büro / yazı masası","te":"Noun","tt":"İsim","de":"An organization or a government department","dt":"Bir organizasyon veya hükümet departmanı","e1":"Federal Bureau of Investigation (FBI).","e1t":"Federal Soruşturma Bürosu.","e2":"Information bureau.","e2t":"Danışma bürosu."},{"w":"burglar","tr":"hırsız (haneye tecavüz eden)","te":"Noun","tt":"İsim","de":"A person who enters a building illegally to steal","dt":"Çalmak amacıyla bir binaya yasadışı giren kişi","e1":"The burglar broke in through the back window.","e1t":"Hırsız arka pencereden içeri girdi.","e2":"A burglar alarm.","e2t":"Hırsız alarmı."},{"w":"burial","tr":"gömme / defin","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The act of putting a dead body into the ground","dt":"Bir cesedin toprağa verilmesi eylemi","e1":"A burial ceremony.","e1t":"Defin (gömme) töreni.","e2":"Burial ground (cemetery).","e2t":"Mezarlık (gömü alanı)."},{"w":"bygone","tr":"geçmiş / mazi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Belonging to a past time","dt":"Geçmiş bir zamana ait olan","e1":"In bygone days.","e1t":"Geçmiş günlerde (mazide).","e2":"Let bygones be bygones.","e2t":"Geçmiş geçmişte kalsın (olan oldu)."},{"w":"bypass","tr":"yan yoldan geçmek / baypas etmek / atlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go around or avoid something","dt":"Bir şeyin etrafından dolanmak veya kaçınmak","e1":"We took the bypass to avoid the city traffic.","e1t":"Şehir trafiğinden kaçınmak için çevre yolunu (yan yolu) kullandık.","e2":"Heart bypass surgery.","e2t":"Kalp baypas ameliyatı."},{"w":"calf","tr":"buzağı / baldır","te":"Noun","tt":"İsim","de":"A young cow; or the back of the lower leg","dt":"Genç inek; veya bacağın alt kısmının arkası","e1":"The cow is nursing its calf.","e1t":"İnek buzağısını emziriyor.","e2":"I pulled a muscle in my calf.","e2t":"Baldırımdaki bir kası incilttim."},{"w":"camouflage","tr":"kamuflaj / gizlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Using colors or patterns to hide someone or something","dt":"Gizlemek için renk veya desen kullanmak","e1":"The soldiers wore camouflage uniforms.","e1t":"Askerler kamuflaj üniformaları giydi.","e2":"The lizard uses camouflage to hide from predators.","e2t":"Kertenkele, avcılardan saklanmak için kamuflaj kullanır."},{"w":"candor / candour","tr":"açık sözlülük / içtenlik","te":"Noun","tt":"İsim","de":"The quality of being honest and telling the truth","dt":"Dürüst olma ve gerçeği söyleme niteliği","e1":"I appreciate your candor.","e1t":"Açık sözlülüğün için minnettarım.","e2":"He spoke with surprising candor about his mistakes.","e2t":"Hataları hakkında şaşırtıcı bir içtenlikle konuştu."},{"w":"cane","tr":"baston / kamış / değnek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long stick used to help someone walk","dt":"Yürümeye yardımcı olan uzun değnek","e1":"He walks with the help of a cane.","e1t":"Bir baston yardımıyla yürüyor.","e2":"Sugar cane.","e2t":"Şeker kamışı."},{"w":"canvas","tr":"tuval / branda / yelken bezi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong heavy cloth used for painting or tents","dt":"Resim veya çadır için kullanılan güçlü ağır kumaş","e1":"The artist painted on a large canvas.","e1t":"Sanatçı büyük bir tuval üzerine resim yaptı.","e2":"Canvas shoes.","e2t":"Bez ayakkabılar."},{"w":"capability","tr":"kapasite / beceri / kabiliyet","te":"Noun","tt":"İsim","de":"The ability or power to do something","dt":"Bir şeyi yapma yeteneği veya gücü","e1":"The company has the capability to handle large projects.","e1t":"Şirket büyük projeleri yürütecek kapasiteye sahip.","e2":"Beyond my technical capabilities.","e2t":"Teknik becerilerimin ötesinde."},{"w":"capitalize / capitalise","tr":"sermayeye çevirmek / büyük harfle yazmak / yararlanmak","te":"Verb","tt":"Fiil","de":"To write in capital letters or to take advantage of something","dt":"Büyük harfle yazmak veya bir durumdan yararlanmak","e1":"Always capitalize the first letter of a sentence.","e1t":"Cümlenin ilk harfini her zaman büyük yazın.","e2":"To capitalize on an opportunity.","e2t":"Bir fırsatı paraya (avantaja) çevirmek."},{"w":"captive","tr":"tutsak / esir","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person or animal whose ability to move is restricted","dt":"Hareket kabiliyeti kısıtlanmış kişi veya hayvan","e1":"The soldiers were taken captive.","e1t":"Askerler esir alındı.","e2":"Animals in captive (captivity).","e2t":"Tutsak (kafes altındaki) hayvanlar."},{"w":"cardiovascular","tr":"kalp","te":"damar","tt":"Adjective","de":"Sıfat","dt":"Relating to the heart and blood vessels","e1":"Kalp ve kan damarlarıyla ilgili","e1t":"Cardiovascular disease.","e2":"Kalp ve damar hastalığı.","e2t":"Cardiovascular system."},{"w":"carpenter","tr":"marangoz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person whose job is making things from wood","dt":"İşi ahşaptan eşyalar yapmak olan kişi","e1":"We hired a carpenter to build the bookshelves.","e1t":"Kitaplıkları yapması için bir marangoz tuttuk.","e2":"Master carpenter.","e2t":"Usta marangoz."},{"w":"cascade","tr":"çağlayan / kademeli akış","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small waterfall or something falling in stages","dt":"Küçük şelale veya aşamalı olarak düşen şey","e1":"A cascade of water.","e1t":"Su çağlayanı.","e2":"The news triggered a cascade of events.","e2t":"Haberler bir dizi olayı (zincirleme/kademeli) tetikledi."},{"w":"casualty","tr":"yaralı / kazazede / zayiat","te":"Noun","tt":"İsim","de":"A person killed or injured in a war or accident","dt":"Savaş veya kazada ölen ya da yaralanan kişi","e1":"There were no casualties in the fire.","e1t":"Yangında zayiat (ölü/yaralı) yoktu.","e2":"Casualty department (ER).","e2t":"Acil servis (yaralı bölümü)."},{"w":"catalyst","tr":"katalizör / etken","te":"Noun","tt":"İsim","de":"A substance that increases the rate of a reaction","dt":"Bir reaksiyonun hızını artıran madde","e1":"The enzyme acts as a catalyst.","e1t":"Enzim bir katalizör görevi görür.","e2":"The protest was a catalyst for change.","e2t":"Protesto, değişim için bir katalizör (tetikleyici) oldu."},{"w":"catastrophe","tr":"felaket / yıkım","te":"Noun","tt":"İsim","de":"A sudden event that causes great suffering or damage","dt":"Büyük acı veya hasara neden olan ani olay","e1":"A natural catastrophe.","e1t":"Doğal afet (felaket).","e2":"The war was a catastrophe for the region.","e2t":"Savaş bölge için bir felaketti."},{"w":"cautious","tr":"temkinli / tedbirli / dikkatli","te":"Adjective","tt":"Sıfat","de":"Avoiding risks and being careful","dt":"Risklerden kaçınan ve dikkatli olan","e1":"He is a very cautious driver.","e1t":"O çok temkinli bir sürücüdür.","e2":"Be cautious about sharing your personal information.","e2t":"Kişisel bilgilerinizi paylaşırken dikkatli olun."},{"w":"cavalry","tr":"süvari birliği / atlı birlik","te":"Noun","tt":"İsim","de":"Soldiers who fight on horses","dt":"At üzerinde savaşan askerler","e1":"The cavalry led the attack.","e1t":"Saldırıya süvariler öncülük etti.","e2":"Modern cavalry (with armored vehicles).","e2t":"Modern süvari (zırhlı araçlı birlik)."},{"w":"census","tr":"nüfus sayımı","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official count of a population","dt":"Nüfusun resmi sayımı","e1":"The government conducts a census every ten years.","e1t":"Hükümet her on yılda bir nüfus sayımı yapar.","e2":"Census data.","e2t":"Nüfus sayımı verileri."},{"w":"ceramic","tr":"seramik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Objects made from clay that has been baked","dt":"Pişmiş kilden yapılan nesneler","e1":"Ceramic tiles.","e1t":"Seramik fayanslar.","e2":"A ceramic vase.","e2t":"Seramik vazo."},{"w":"certify","tr":"belgelemek / onaylamak / sertifika vermek","te":"Verb","tt":"Fiil","de":"To state officially that something is true","dt":"Bir şeyin doğru olduğunu resmi olarak belirtmek","e1":"The accounts were certified as correct.","e1t":"Hesapların doğruluğu onaylandı (belgelendi).","e2":"A certified English teacher.","e2t":"Sertifikalı İngilizce öğretmeni."},{"w":"chaos","tr":"kaos / kargaşa","te":"Noun","tt":"İsim","de":"A state of total confusion and lack of order","dt":"Tam bir kafa karışıklığı ve düzen eksikliği durumu","e1":"The city was in chaos after the earthquake.","e1t":"Depremden sonra şehir kaos içindeydi.","e2":"Utter chaos.","e2t":"Tam bir keşmekeş."},{"w":"charter","tr":"tüzük / şartname / kiralamak (gemi/uçak)","te":"Noun/Verb/Adj","tt":"A formal statement of rights or a travel agreement","de":"Hakların resmi bildirimi veya seyahat anlaşması","dt":"The UN Charter.","e1":"BM Tüzüğü (Şartı).","e1t":"We chartered a boat for the trip.","e2":"Gezi için bir tekne kiraladık.","e2t":""},{"w":"cherish","tr":"değer vermek / şefkatle bakmak / beslemek (duygu)","te":"Verb","tt":"Fiil","de":"To love and protect someone or something very much","dt":"Birini veya bir şeyi çok sevmek ve korumak","e1":"I cherish the memories of our childhood.","e1t":"Çocukluk anılarımıza değer veriyorum.","e2":"He cherished his freedom.","e2t":"Özgürlüğünü her şeyden üstün tuttu."},{"w":"choke","tr":"nefessiz bırakmak / tıkanmak / boğulmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop breathing because something is in the throat","dt":"Boğazda bir şey olduğu için nefes alamamak","e1":"He nearly choked on a piece of meat.","e1t":"Bir parça et yüzünden neredeyse boğuluyordu.","e2":"The roads were choked with traffic.","e2t":"Yollar trafikten tıkanmıştı."},{"w":"chronic","tr":"kronik / müzmin","te":"Adjective","tt":"Sıfat","de":"(Of a disease or problem) lasting for a long time","dt":"(Hastalık veya sorun için) uzun süre devam eden","e1":"Chronic back pain.","e1t":"Kronik bel ağrısı.","e2":"Chronic unemployment.","e2t":"Müzmin (süregelen) işsizlik."},{"w":"circuit","tr":"devre / tur / çevrim","te":"Noun/Verb","tt":"İsim/Fiil","de":"A closed path for an electric current","dt":"Elektrik akımı için kapalı yol","e1":"Short circuit.","e1t":"Kısa devre.","e2":"An integrated circuit (IC).","e2t":"Entegre devre (çip)."},{"w":"circulate","tr":"dolaşmak / devretmek / yayılmak","te":"Verb","tt":"Fiil","de":"To move around continuously","dt":"Sürekli olarak etrafta hareket etmek","e1":"Blood circulates through the body.","e1t":"Kan vücutta dolaşır.","e2":"Rumors began to circulate.","e2t":"Söylentiler yayılmaya başladı."},{"w":"circulation","tr":"dolaşım / tiraj (gazete) / sirkülasyon","te":"Noun","tt":"İsim","de":"The movement of blood or the number of papers sold","dt":"Kanın hareketi veya satılan gazete sayısı","e1":"Good blood circulation.","e1t":"İyi kan dolaşımı.","e2":"The magazine has a circulation of 50,000.","e2t":"Derginin 50.000 tirajı var."},{"w":"circumvent","tr":"atlatmak / etrafından dolanmak / kaçınmak","te":"Verb","tt":"Fiil","de":"To avoid something, especially cleverly or illegally","dt":"Bir şeyden, özellikle zekice veya yasadışı yolla kaçınmak","e1":"They tried to circumvent the tax laws.","e1t":"Vergi yasalarını atlatmaya (çevresinden dolanmaya) çalıştılar.","e2":"To circumvent a problem.","e2t":"Bir sorunu aşmak (etrafından dolanmak)."},{"w":"cite","tr":"alıntı yapmak / bahsetmek / (mahkemeye) çağırmak","te":"Verb","tt":"Fiil","de":"To mention something as a proof or example","dt":"Bir şeyi kanıt veya örnek olarak belirtmek","e1":"He cited several reasons for his decision.","e1t":"Kararı için birkaç neden belirtti (alıntıladı).","e2":"Please cite your sources.","e2t":"Lütfen kaynaklarınızı belirtin."},{"w":"civic","tr":"şehirle ilgili / sivil / vatani","te":"Adjective","tt":"Sıfat","de":"Relating to a city or to people who live there","dt":"Bir şehirle veya orada yaşayan insanlarla ilgili","e1":"Civic duty.","e1t":"Vatandaşlık görevi.","e2":"Civic pride.","e2t":"Şehirle duyulan gurur."},{"w":"civilization","tr":"medeniyet / uygarlık","te":"Noun","tt":"İsim","de":"A highly developed human society","dt":"Gelişmiş insan toplumu","e1":"Ancient civilizations.","e1t":"Antik medeniyetler.","e2":"Western civilization.","e2t":"Batı medeniyeti."},{"w":"civilize / civilise","tr":"uygarlaştırmak / medenileştirmek","te":"Verb","tt":"Fiil","de":"To educate a society so that its culture becomes more developed","dt":"Bir toplumu kültürünü geliştirecek şekilde eğitmek","e1":"The Romans civilized many parts of Europe.","e1t":"Romalılar Avrupa'nın birçok bölgesini uygarlaştırdı.","e2":"To civilize the wild regions.","e2t":"Vahşi bölgeleri medenileştirmek."},{"w":"clash","tr":"çatışmak / çarpışmak / uyuşmamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fight or to disagree strongly","dt":"Savaşmak veya güçlü bir şekilde uyuşmamak","e1":"Protesters clashed with the police.","e1t":"Protestocular polisle çatıştı.","e2":"Their interests clash.","e2t":"Çıkarları çatışıyor."},{"w":"cleanse","tr":"arındırmak / temizlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something completely clean","dt":"Bir şeyi tamamen temiz (saf) hale getirmek","e1":"To cleanse the skin.","e1t":"Cildi arındırmak.","e2":"Ethnic cleansing (political term).","e2t":"Etnik temizlik."},{"w":"clergy","tr":"ruhban sınıfı / din adamları","te":"Noun","tt":"İsim","de":"Religious leaders like priests or imams","dt":"Rahip veya imam gibi dini liderler","e1":"A member of the clergy.","e1t":"Ruhban sınıfından bir üye (din adamı).","e2":"The clergy and the laity.","e2t":"Din adamları ve halk (ruhban olmayanlar)."},{"w":"climatic","tr":"iklimle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the climate","dt":"İklim ile ilgili","e1":"Climatic changes.","e1t":"İklimsel değişiklikler.","e2":"Climatic conditions.","e2t":"İklim koşulları."},{"w":"clip","tr":"kırpmak / mandal / ataş / klip","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small object for holding things; or a short video","dt":"Bir şeyleri tutmak için küçük nesne; veya kısa video","e1":"Paper clip.","e1t":"Ataş.","e2":"I watched a short clip of the movie.","e2t":"Filmin kısa bir klibini izledim."},{"w":"clockwise","tr":"saat yönünde","te":"Adverb/Adjective","tt":"In the same direction as the hands of a clock","de":"Saat yelkovanının hareket ettiği yönde","dt":"Turn the knob clockwise.","e1":"Düğmeyi saat yönünde çevirin.","e1t":"A clockwise movement.","e2":"Saat yönünde bir hareket.","e2t":""},{"w":"clone","tr":"klonlamak / klon / tıpatıp aynısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A plant or animal that is an exact copy","dt":"Tam bir kopya olan bitki veya hayvan","e1":"Dolly the sheep was the first mammal clone.","e1t":"Koyun Dolly ilk memeli klonuydu.","e2":"To clone a cell.","e2t":"Bir hücreyi klonlamak."},{"w":"closure","tr":"kapanış / kapatma / kabullenme","te":"Noun","tt":"İsim","de":"The act of closing something or a feeling of finality","dt":"Bir şeyi kapatma eylemi veya bir sonlanma/huzur hissi","e1":"Factory closure.","e1t":"Fabrikanın kapatılması.","e2":"The victim's family needed closure.","e2t":"Kurbanın ailesinin bir kabullenmeye (olayın sonlanmasına) ihtiyacı vardı."},{"w":"cluster","tr":"küme / salkım / toplanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of similar things that are close together","dt":"Birbirine yakın benzer şeylerin grubu","e1":"A cluster of stars.","e1t":"Yıldız kümesi.","e2":"People clustered around the accident.","e2t":"İnsanlar kazanın etrafında kümelendi."},{"w":"clutch","tr":"kavramak / debriyaj / pençe","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hold something tightly; or a part of a car","dt":"Bir şeyi sıkıca tutmak; veya arabanın bir parçası","e1":"He clutched his bag tightly.","e1t":"Çantasını sıkıca kavradı.","e2":"Put your foot on the clutch.","e2t":"Ayağını debriyaja koy."},{"w":"coalition","tr":"koalisyon / ittifak","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A group of people or countries joined for a purpose","dt":"Bir amaç için birleşmiş insanlar veya ülkeler grubu","e1":"A coalition government.","e1t":"Koalisyon hükümeti.","e2":"To form a coalition.","e2t":"Koalisyon kurmak."},{"w":"coarse","tr":"kaba / pürüzlü / nahoş","te":"Adjective","tt":"Sıfat","de":"Rough and thick; or rude","dt":"Sert ve kalın; veya kaba","e1":"Coarse sand.","e1t":"Kalın (pürüzlü) kum.","e2":"Coarse language.","e2t":"Kaba (küfürlü) dil."},{"w":"coherent","tr":"tutarlı / uyumlu","te":"Adjective","tt":"Sıfat","de":"Clear and logical; with all parts connecting well","dt":"Net ve mantıklı; tüm parçaları iyi bağlanan","e1":"He was able to give a coherent account of the incident.","e1t":"Olayla ilgili tutarlı bir açıklama yapabildi.","e2":"A coherent policy.","e2t":"Tutarlı bir politika."},{"w":"collaborate","tr":"işbirliği yapmak","te":"Verb","tt":"Fiil","de":"To work together for a particular purpose","dt":"Belirli bir amaç için birlikte çalışmak","e1":"Researchers from different universities collaborated on the project.","e1t":"Farklı üniversitelerden araştırmacılar projede işbirliği yaptı.","e2":"To collaborate with the enemy.","e2t":"Düşmanla işbirliği yapmak."},{"w":"collaboration","tr":"işbirliği","te":"Noun","tt":"İsim","de":"The act of working together","dt":"Birlikte çalışma eylemi","e1":"The project was a collaboration between two schools.","e1t":"Proje iki okul arasındaki bir işbirliğiydi.","e2":"In collaboration with...","e2t":"... ile işbirliği içinde."},{"w":"collide","tr":"çarpışmak / çatışmak","te":"Verb","tt":"Fiil","de":"To hit something or someone that is moving","dt":"Hareket eden bir şeye veya birine çarpmak","e1":"The two cars collided at the intersection.","e1t":"İki araba kavşakta çarpıştı.","e2":"Their interests often collide.","e2t":"Çıkarları sık sık çatışır."},{"w":"colonial","tr":"sömürgecilikle ilgili / sömürge","te":"Adjective","tt":"Sıfat","de":"Relating to a colony or colonialism","dt":"Bir sömürge veya sömürgecilikle ilgili","e1":"Colonial rule.","e1t":"Sömürge yönetimi.","e2":"A colonial building.","e2t":"Sömürge dönemine ait bina."},{"w":"colony","tr":"koloni / sömürge","te":"Noun","tt":"İsim","de":"A country or area controlled by a more powerful country","dt":"Daha güçlü bir ülke tarafından kontrol edilen ülke veya bölge","e1":"Former British colonies.","e1t":"Eski İngiliz sömürgeleri.","e2":"A colony of ants.","e2t":"Karınca kolonisi."},{"w":"combat","tr":"çarpışma / mücadele / dövüşmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fight between armed forces; or to try to stop something","dt":"Silahlı güçler arası savaş; veya bir şeyi durdurmaya çalışmak","e1":"Hand","e1t":"to","e2":"hand combat.","e2t":"Göğüs göğüse çarpışma."},{"w":"comedian","tr":"komedyen","te":"Noun","tt":"İsim","de":"A person whose job is to make people laugh","dt":"İşi insanları güldürmek olan kişi","e1":"He is a famous stand","e1t":"up comedian.","e2":"O ünlü bir stand","e2t":"up komedyenidir."},{"w":"commence","tr":"başlamak","te":"Verb","tt":"Fiil","de":"To begin something","dt":"Bir şeye başlamak","e1":"The ceremony will commence at 10 AM.","e1t":"Tören saat 10'da başlayacak.","e2":"Shall we commence?","e2t":"Başlayalım mı?"},{"w":"commentary","tr":"yorum / eleştiri / naklen yayın anlatımı","te":"Noun","tt":"İsim","de":"A spoken or written description of an event or book","dt":"Bir olay veya kitabın sözlü veya yazılı açıklaması","e1":"A running commentary on the match.","e1t":"Maçın naklen anlatımı (yorumu).","e2":"Social commentary.","e2t":"Sosyal eleştiri."},{"w":"commerce","tr":"ticaret","te":"Noun","tt":"Isim","de":"The activities involved in buying and selling things","dt":"Mal alım satımıyla ilgili faaliyetler","e1":"Chamber of Commerce.","e1t":"Ticaret Odası.","e2":"E","e2t":"commerce."},{"w":"compact","tr":"sıkıştırmak / kompakt / küçük ve kullanışlı","te":"Verb/Adjective/Noun","tt":"Small but arranged to make good use of space","de":"Küçük ama alanı iyi kullanan","dt":"A compact car.","e1":"Kompakt (küçük) araba.","e1t":"The soil was compacted.","e2":"Toprak sıkıştırılmıştı.","e2t":""},{"w":"comparative","tr":"kıyaslamalı / göreceli / karşılaştırmalı","te":"Adjective","tt":"Sıfat","de":"Comparing one thing with another","dt":"Bir şeyi diğeriyle karşılaştıran","e1":"A comparative study of two languages.","e1t":"İki dilin karşılaştırmalı çalışması.","e2":"He is a comparative stranger.","e2t":"O nispeten (göreceli olarak) bir yabancı."},{"w":"compel","tr":"zorlamak / mecbur etmek","te":"Verb","tt":"Fiil","de":"To force someone to do something","dt":"Birini bir şey yapmaya zorlamak","e1":"The law compels companies to pay taxes.","e1t":"Kanun, şirketleri vergi ödemeye zorlar.","e2":"I felt compelled to tell the truth.","e2t":"Doğruyu söylemek zorunda (mecbur) hissettim."},{"w":"compensation","tr":"tazminat / telafi","te":"Noun","tt":"İsim","de":"Money paid to someone because of injury or loss","dt":"Yaralanma veya kayıp nedeniyle ödenen para","e1":"He received compensation for his injuries.","e1t":"Yaralanmaları için tazminat aldı.","e2":"Over","e2t":"compensation."},{"w":"competence","tr":"yetkinlik / yeterlilik","te":"Noun","tt":"İsim","de":"The ability to do something well","dt":"Bir şeyi iyi yapma yeteneği","e1":"Professional competence.","e1t":"Mesleki yetkinlik.","e2":"He reached a high level of competence in English.","e2t":"İngilizcede yüksek bir yetkinlik seviyesine ulaştı."},{"w":"competent","tr":"yetkin / becerikli / yeterli","te":"Adjective","tt":"Sıfat","de":"Having the skills to do something well","dt":"Bir şeyi iyi yapacak becerilere sahip olan","e1":"A competent teacher.","e1t":"Yetkin (yeterli) bir öğretmen.","e2":"He is very competent at his job.","e2t":"İşinde çok beceriklidir."},{"w":"compile","tr":"derlemek / toplamak","te":"Verb","tt":"Fiil","de":"To collect information from different places and arrange it","dt":"Farklı yerlerden bilgi toplamak ve düzenlemek","e1":"We are compiling a list of vocabulary.","e1t":"Bir kelime listesi derliyoruz.","e2":"The report took weeks to compile.","e2t":"Raporun derlenmesi haftalar sürdü."},{"w":"complexion","tr":"cilt yapısı / ten rengi / görünüm","te":"Noun","tt":"İsim","de":"The natural color and appearance of the skin on a person's face","dt":"Bir kişinin yüzündeki cildin doğal rengi ve görünümü","e1":"She has a pale complexion.","e1t":"Solgun bir teni (cilt yapısı) var.","e2":"To give a new complexion to the problem.","e2t":"Soruna yeni bir görünüm (boyut) kazandırmak."},{"w":"complexity","tr":"karmaşıklık","te":"Noun","tt":"İsim","de":"The state of having many parts and being difficult to understand","dt":"Birçok parçaya sahip olma ve anlaşılması zor olma durumu","e1":"The complexity of the human brain.","e1t":"İnsan beyninin karmaşıklığı.","e2":"To reduce the complexity of the code.","e2t":"Kodun karmaşıklığını azaltmak."},{"w":"compliance","tr":"uyum / riayet","te":"Noun","tt":"İsim","de":"The act of obeying an order or rule","dt":"Bir emre veya kurala uyma eylemi","e1":"In compliance with the safety regulations.","e1t":"Güvenlik düzenlemelerine uygun olarak (uyum içinde).","e2":"Environmental compliance.","e2t":"Çevre kurallarına riayet."},{"w":"complicate","tr":"zorlaştırmak / karmaşık hale getirmek","te":"Verb","tt":"Fiil","de":"To make something more difficult to deal with","dt":"Bir şeyi başa çıkılması daha zor hale getirmek","e1":"Don't complicate the situation.","e1t":"Durumu karmaşıklaştırma.","e2":"The engine problem was complicated by a leak.","e2t":"Motor sorunu bir sızıntıyla daha da karmaşıklaştı."},{"w":"compliment","tr":"iltifat / övgü / iltifat etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A remark that expresses approval or admiration","dt":"Onay veya hayranlık ifade eden söz","e1":"He paid her a compliment.","e1t":"Ona bir iltifat etti.","e2":"I take that as a compliment.","e2t":"Bunu bir iltifat olarak kabul ediyorum."},{"w":"comply","tr":"uymak / itaat etmek","te":"Verb","tt":"Fiil","de":"To obey a rule or order","dt":"Bir kurala veya emre uymak","e1":"Companies must comply with the law.","e1t":"Şirketler yasaya uymak zorundadır.","e2":"He refused to comply with my request.","e2t":"Talebime uymayı reddetti."},{"w":"composite","tr":"bileşik / karma","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Made of several different parts or materials","dt":"Birkaç farklı parça veya malzemeden yapılmış","e1":"A composite picture.","e1t":"Birleşik (birkaç fotoğraftan oluşan) resim.","e2":"Composite materials.","e2t":"Kompozit (bileşik) malzemeler."},{"w":"compulsory","tr":"zorunlu","te":"Adjective","tt":"Sıfat","de":"If something is compulsory, you must do it","dt":"Eğer bir şey zorunluysa, onu yapmalısınız","e1":"English is a compulsory subject in schools.","e1t":"İngilizce okullarda zorunlu bir derstir.","e2":"Compulsory military service.","e2t":"Zorunlu askerlik hizmeti."},{"w":"conceal","tr":"gizlemek / saklamak","te":"Verb","tt":"Fiil","de":"To hide something","dt":"Bir şeyi saklamak","e1":"He tried to conceal his anger.","e1t":"Öfkesini gizlemeye çalıştı.","e2":"The gun was concealed under his coat.","e2t":"Silah paltosunun altına gizlenmişti."},{"w":"concede","tr":"kabul etmek (isteksizce) / yenilgiyi kabul etmek","te":"Verb","tt":"Fiil","de":"To admit that something is true or that you have lost","dt":"Bir şeyin doğru olduğunu veya kaybettiğinizi kabul etmek","e1":"He finally conceded that I was right.","e1t":"Sonunda haklı olduğumu (isteksizce) kabul etti.","e2":"The candidate conceded defeat.","e2t":"Aday yenilgiyi kabul etti."},{"w":"conceive","tr":"tasarlamak / kurgulamak / hamile kalmak","te":"Verb","tt":"Fiil","de":"To form an idea or to become pregnant","dt":"Bir fikir oluşturmak veya hamile kalmak","e1":"I cannot conceive of a world without music.","e1t":"Müziksiz bir dünya hayal edemiyorum (kurgulayamıyorum).","e2":"The project was conceived ten years ago.","e2t":"Proje on yıl önce tasarlandı."},{"w":"conceptual","tr":"kavramsal","te":"Adjective","tt":"Sıfat","de":"Relating to abstract ideas","dt":"Soyut fikirlerle ilgili","e1":"Conceptual art.","e1t":"Kavramsal sanat.","e2":"A conceptual framework.","e2t":"Kavramsal bir çerçeve."},{"w":"concession","tr":"taviz / ödün / imtiyaz","te":"Noun","tt":"İsim","de":"Something that you allow someone to have in order to end an argument","dt":"Bir tartışmayı bitirmek için birine verdiğiniz şey","e1":"The government made concessions to the strikers.","e1t":"Hükümet grevcilere tavizler verdi.","e2":"To grant a concession.","e2t":"İmtiyaz tanımak."},{"w":"concise","tr":"öz / kısa ve net","te":"Adjective","tt":"Sıfat","de":"Short and clear, without unnecessary words","dt":"Kısa ve net, gereksiz kelimeler olmadan","e1":"A concise summary.","e1t":"Öz (kısa ve net) bir özet.","e2":"Please keep your answers concise.","e2t":"Lütfen cevaplarınızı kısa tutun."},{"w":"condemn","tr":"kınamak / mahkum etmek","te":"Verb","tt":"Fiil","de":"To say strongly that you do not approve of something","dt":"Bir şeyi onaylamadığınızı güçlü bir şekilde söylemek","e1":"The UN condemned the terrorist attack.","e1t":"BM terör saldırısını kınadı.","e2":"He was condemned to death.","e2t":"Ölüme mahkum edildi."},{"w":"cone","tr":"koni / dondurma külahı","te":"Noun","tt":"Isim","de":"A shape with a circular base and a pointed top","dt":"Dairesel tabanlı ve sivri tepeli şekil","e1":"Traffic cone.","e1t":"Trafik konisi.","e2":"Ice cream cone.","e2t":"Dondurma külahı."},{"w":"confession","tr":"itiraf","te":"Noun","tt":"İsim","de":"The act of admitting that you have done something wrong","dt":"Yanlış bir şey yaptığını kabul etme eylemi","e1":"He made a full confession to the police.","e1t":"Polise tam bir itirafta bulundu.","e2":"Signed confession.","e2t":"İmzalı itiraf."},{"w":"configuration","tr":"yapılandırma / düzenleşim","te":"Noun","tt":"İsim","de":"The particular arrangement of the parts of something","dt":"Bir şeyin parçalarının özel düzeni","e1":"System configuration.","e1t":"Sistem yapılandırması.","e2":"The configuration of the molecules.","e2t":"Moleküllerin dizilimi (yapılandırması)."},{"w":"confine","tr":"sınırlamak / hapsetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep someone or something within limits","dt":"Birini veya bir şeyi sınırlar içinde tutmak","e1":"Please confine your comments to the topic.","e1t":"Lütfen yorumlarınızı konuyla sınırlayın.","e2":"He was confined to a wheelchair.","e2t":"Tekerlekli sandalyeye mahkumdu (sınırlıydı)."},{"w":"confiscate","tr":"el koymak / müsadere etmek","te":"Verb","tt":"Fiil","de":"To take something away from someone as a punishment","dt":"Ceza olarak birinin elinden bir şeyi almak","e1":"The teacher confiscated my phone.","e1t":"Öğretmen telefonuma el koydu.","e2":"The police confiscated the illegal goods.","e2t":"Polis yasadışı mallara el koydu."},{"w":"conform","tr":"uymak / uyum sağlamak","te":"Verb","tt":"Fiil","de":"To behave according to rules or social standards","dt":"Kurallara veya sosyal standartlara göre davranmak","e1":"You must conform to the rules of the school.","e1t":"Okul kurallarına uymalısınız.","e2":"Pressure to conform.","e2t":"Uyum sağlama (topluma uyma) baskısı."},{"w":"congregate","tr":"toplanmak / bir araya gelmek","te":"Verb","tt":"Fiil","de":"To gather together in a large group","dt":"Büyük bir grup halinde bir araya gelmek","e1":"A crowd began to congregate in the square.","e1t":"Meydanda bir kalabalık toplanmaya başladı.","e2":"People congregate to worship.","e2t":"İnsanlar ibadet etmek için toplanır."},{"w":"conjunction","tr":"bağlaç / birleşme","te":"Noun","tt":"İsim","de":"A word used to connect clauses; or a combination","dt":"Cümlecikleri bağlamak için kullanılan kelime; veya birleşim","e1":"In conjunction with (together with).","e1t":"... ile bağlantılı olarak (birlikte).","e2":"\"And\" is a conjunction.","e2t":"\"And\" bir bağlaçtır."},{"w":"conquer","tr":"fethetmek / yenmek","te":"Verb","tt":"Fiil","de":"To take control of a country by force; or to defeat","dt":"Bir ülkeyi zorla ele geçirmek; veya yenmek","e1":"The Romans conquered most of Europe.","e1t":"Romalılar Avrupa'nın çoğunu fethetti.","e2":"To conquer your fears.","e2t":"Korkularını yenmek."},{"w":"conscience","tr":"vicdan","te":"Noun","tt":"İsim","de":"The part of your mind that tells you what is right or wrong","dt":"Zihninizin neyin doğru veya yanlış olduğunu söyleyen kısmı","e1":"A guilty conscience.","e1t":"Vicdan azabı (suçlu vicdan).","e2":"For conscience's sake.","e2t":"Vicdan huzuru için."},{"w":"consecutive","tr":"ardışık / üst üste","te":"Adjective","tt":"Sıfat","de":"Following one after another without an interruption","dt":"Kesintisiz bir şekilde birbirini izleyen","e1":"It rained for five consecutive days.","e1t":"Üst üste (ardışık) beş gün yağmur yağdı.","e2":"Consecutive interpretation.","e2t":"Ardıl çeviri."},{"w":"consensus","tr":"fikir birliği / mutabakat","te":"Noun","tt":"İsim","de":"A general agreement among a group of people","dt":"Bir grup insan arasındaki genel anlaşma","e1":"They reached a consensus after a long discussion.","e1t":"Uzun bir tartışmadan sonra fikir birliğine vardılar.","e2":"National consensus.","e2t":"Ulusal mutabakat."},{"w":"conservation","tr":"koruma / muhafaza (doğa vb.)","te":"Noun","tt":"İsim","de":"The protection of nature or old buildings","dt":"Doğanın veya eski binaların korunması","e1":"Wildlife conservation.","e1t":"Yaban hayatını koruma.","e2":"Water conservation.","e2t":"Su tasarrufu (korunması)."},{"w":"conserve","tr":"korumak / muhafaza etmek / tasarruf etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep and protect something from damage or waste","dt":"Bir şeyi hasardan veya israftan korumak","e1":"We must conserve energy.","e1t":"Enerjiden tasarruf etmeliyiz (korumalıyız).","e2":"To conserve natural resources.","e2t":"Doğal kaynakları korumak."},{"w":"considerable","tr":"oldukça fazla / önemli ölçüde","te":"Adjective","tt":"Sıfat","de":"Large or important enough to have an effect","dt":"Etki yaratacak kadar büyük veya önemli","e1":"A considerable amount of money.","e1t":"Oldukça fazla miktarda para.","e2":"Considerable progress.","e2t":"Önemli (kayda değer) ilerleme."},{"w":"considerate","tr":"düşünceli / saygılı","te":"Adjective","tt":"Sıfat","de":"Kind and helpful who thinks of others' feelings","dt":"Nazik ve başkalarının duygularını düşünen","e1":"It was very considerate of you to call.","e1t":"Araman çok düşünceli bir hareketti.","e2":"A considerate neighbor.","e2t":"Düşünceli bir komşu."},{"w":"consolidate","tr":"sağlamlaştırmak / birleştirmek","te":"Verb","tt":"Fiil","de":"To become or make something stronger or more solid","dt":"Bir şeyi daha güçlü veya sağlam hale getirmek/birleştirmek","e1":"The company is trying to consolidate its position.","e1t":"Şirket konumunu sağlamlaştırmaya çalışıyor.","e2":"To consolidate several departments into one.","e2t":"Birkaç departmanı bir tanesinde birleştirmek."},{"w":"conspicuous","tr":"dikkat çekici / göze batan","te":"Adjective","tt":"Sıfat","de":"Very noticeable or attracting attention","dt":"Çok fark edilen veya dikkat çeken","e1":"He felt conspicuous in his bright red suit.","e1t":"Parlak kırmızı takım elbisesiyle kendini çok dikkat çekici (göze batan) hissetti.","e2":"Conspicuous consumption.","e2t":"Gösterişçi tüketim."},{"w":"constrain","tr":"zorlamak / kısıtlamak","te":"Verb","tt":"Fiil","de":"To control or limit something; to force someone","dt":"Bir şeyi kontrol etmek veya sınırlamak; birini zorlamak","e1":"Financial problems constrained our growth.","e1t":"Finansal sorunlar büyümemizi kısıtladı.","e2":"I felt constrained to agree.","e2t":"Kabul etmek zorunda (zorlanmış) hissettim."},{"w":"consultation","tr":"danışma / görüşme / konsültasyon","te":"Noun","tt":"İsim","de":"A meeting with an expert to seek advice","dt":"Tavsiye almak için bir uzmanla yapılan görüşme","e1":"The decision was made after consultation with experts.","e1t":"Karar, uzmanlara danışıldıktan sonra verildi.","e2":"Medical consultation.","e2t":"Tıbbi konsültasyon."},{"w":"consumption","tr":"tüketim","te":"Noun","tt":"İsim","de":"The act of using, eating, or drinking something","dt":"Bir şeyi kullanma, yeme veya içme eylemi","e1":"Fuel consumption.","e1t":"Yakıt tüketimi.","e2":"The consumption of alcohol is prohibited here.","e2t":"Burada alkol tüketimi yasaktır."},{"w":"contagious","tr":"bulaşıcı","te":"Adjective","tt":"Sıfat","de":"(Of a disease) spread by contact; or catching (laughter)","dt":"(Hastalık için) temasla yayılan; veya bulaşıcı (gülme vb.)","e1":"A highly contagious virus.","e1t":"Son derece bulaşıcı bir virüs.","e2":"Her enthusiasm was contagious.","e2t":"Onun coşkusu bulaşıcıydı."},{"w":"contender","tr":"rakip / aday","te":"Noun","tt":"İsim","de":"Someone who competes with others for a prize or title","dt":"Bir ödül veya unvan için başkalarıyla yarışan kişi","e1":"He is a leading contender for the gold medal.","e1t":"Altın madalya için önde gelen bir adaydır (rakiptir).","e2":"Title contender.","e2t":"Şampiyonluk adayı."},{"w":"contextual","tr":"bağlamsal","te":"Adjective","tt":"Sıfat","de":"Relating to the context of something","dt":"Bir şeyin bağlamıyla ilgili","e1":"Contextual clues.","e1t":"Bağlamsal ipuçları.","e2":"We need to look at the contextual factors.","e2t":"Bağlamsal faktörlere bakmamız gerekiyor."},{"w":"contingency","tr":"beklenmedik durum / ihtimal / pay","te":"Noun","tt":"İsim","de":"A possibility of something that may happen in the future","dt":"Gelecekte gerçekleşebilecek bir şeyin ihtimali","e1":"We need a contingency plan.","e1t":"Bir acil durum (beklenmedik durum) planına ihtiyacımız var.","e2":"Contingency fund.","e2t":"İhtiyat akçesi (beklenmedik durum fonu)."},{"w":"contradiction","tr":"çelişki","te":"Noun","tt":"İsim","de":"A lack of agreement between facts or ideas","dt":"Gerçekler veya fikirler arasındaki uyumsuzluk","e1":"There is a contradiction between his words and his actions.","e1t":"Sözleri ve eylemleri arasında bir çelişki var.","e2":"A contradiction in terms.","e2t":"Kendi içinde çelişkili ifade."},{"w":"contributor","tr":"katkı sağlayan / bağışçı / yazar","te":"Noun","tt":"İsim","de":"Someone who gives money or help; or a writer for a magazine","dt":"Para veya yardım veren kişi; veya dergi yazarı","e1":"He is a regular contributor to the magazine.","e1t":"Derginin düzenli bir yazarıdır (katkı sağlayanıdır).","e2":"A major contributor to global warming.","e2t":"Küresel ısınmaya katkıda bulunan ana etken."},{"w":"controversy","tr":"tartışma / anlaşmazlık / polemik","te":"Noun","tt":"İsim","de":"A lot of disagreement about something","dt":"Bir şey hakkında çok fazla anlaşmazlık","e1":"The new law caused a lot of controversy.","e1t":"Yeni yasa büyük bir tartışmaya (polemiğe) neden oldu.","e2":"Beyond controversy.","e2t":"Tartışmasız."},{"w":"conventional","tr":"geleneksel / alışılagelmiş","te":"Adjective","tt":"Sıfat","de":"Following what is traditional or usual","dt":"Geleneksel veya alışılmış olanı takip eden","e1":"Conventional medicine.","e1t":"Geleneksel tıp.","e2":"He has very conventional views.","e2t":"Çok geleneksel (alışılagelmiş) görüşleri var."},{"w":"conversion","tr":"dönüşüm / çevirme / din değiştirme","te":"Noun","tt":"İsim","de":"The process of changing something from one form to another","dt":"Bir şeyi bir formdan diğerine değiştirme süreci","e1":"Data conversion.","e1t":"Veri dönüşümü.","e2":"The conversion of the attic into a bedroom.","e2t":"Çatı katının yatak odasına dönüştürülmesi."},{"w":"conviction","tr":"mahkumiyet / inanç / kanaat","te":"Noun","tt":"İsim","de":"The fact of being found guilty; or a strong belief","dt":"Suçlu bulunma durumu; veya güçlü bir inanç","e1":"He has a previous conviction for theft.","e1t":"Hırsızlıktan sabıkası (mahkumiyeti) var.","e2":"It is my firm conviction that...","e2t":"... olduğu benim sarsılmaz inancımdır."},{"w":"coordination","tr":"koordinasyon / eşgüdüm","te":"Noun","tt":"İsim","de":"The act of making parts work together well","dt":"Parçaların birlikte iyi çalışmasını sağlama eylemi","e1":"Hand","e1t":"eye coordination.","e2":"El","e2t":"göz koordinasyonu."},{"w":"cope","tr":"baş etmek / üstesinden gelmek","te":"Verb","tt":"Fiil","de":"To deal successfully with a difficult situation","dt":"Zor bir durumla başarıyla ilgilenmek","e1":"He is struggling to cope with the stress.","e1t":"Stresle baş etmekte zorlanıyor.","e2":"I can't cope anymore.","e2t":"Artık üstesinden gelemiyorum."},{"w":"copper","tr":"bakır","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A reddish","dt":"brown metal","e1":"Kızılımsı kahverengi metal","e1t":"Copper pipes.","e2":"Bakır borular.","e2t":"Copper is a good conductor of electricity."},{"w":"copyright","tr":"telif hakkı","te":"Noun/Verb/Adj","tt":"The legal right to control the use of your work","de":"Eserinizin kullanımını kontrol etme yasal hakkı","dt":"Copyright law.","e1":"Telif hakkı yasası.","e1t":"All rights reserved, copyright 2026.","e2":"Tüm hakları saklıdır, telif hakkı 2026.","e2t":""},{"w":"coral","tr":"mercan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard substance formed by small sea animals","dt":"Küçük deniz hayvanları tarafından oluşturulan sert madde","e1":"Coral reef.","e1t":"Mercan resifi.","e2":"Coral necklace.","e2t":"Mercan kolye."},{"w":"corpse","tr":"ceset","te":"Noun","tt":"İsim","de":"A dead body, especially of a human","dt":"Ölü vücut, özellikle insan vücudu","e1":"The corpse was identified by fingerprints.","e1t":"Cesedin kimliği parmak izlerinden tespit edildi.","e2":"To examine a corpse.","e2t":"Bir cesedi incelemek."},{"w":"correlation","tr":"ilişki / bağlantı / korelasyon","te":"Noun","tt":"İsim","de":"A connection between two or more things","dt":"İki veya daha fazla şey arasındaki bağlantı","e1":"A high correlation between smoking and lung cancer.","e1t":"Sigara ve akciğer kanseri arasında yüksek bir ilişki (korelasyon).","e2":"Statistical correlation.","e2t":"İstatistiksel korelasyon."},{"w":"correspondence","tr":"yazışma / mektuplaşma / uyum","te":"Noun","tt":"İsim","de":"Letters or emails; or a connection between things","dt":"Mektuplar veya e","e1":"postalar; veya şeyler arasındaki bağlantı","e1t":"Business correspondence.","e2":"Ticari yazışma.","e2t":"There is a close correspondence between the two maps."},{"w":"cosmic","tr":"evrensel / kozmik / uzay ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the universe and space","dt":"Evren ve uzay ile ilgili","e1":"Cosmic rays.","e1t":"Kozmik ışınlar.","e2":"A disaster of cosmic proportions.","e2t":"Evrensel boyutlarda bir felaket."},{"w":"cosmopolitan","tr":"kozmopolit / dünya vatandaşı","te":"Adjective","tt":"Sıfat","de":"Including people from many different countries","dt":"Birçok farklı ülkeden insanı barındıran","e1":"London is a very cosmopolitan city.","e1t":"Londra çok kozmopolit bir şehirdir.","e2":"A cosmopolitan outlook.","e2t":"Dünyaya açık (kozmopolit) bir bakış açısı."},{"w":"costume","tr":"kostüm / kıyafet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A set of clothes worn by an actor or for a party","dt":"Oyuncunun veya parti için giyilen kıyafet seti","e1":"He wore a Batman costume.","e1t":"Batman kostümü giydi.","e2":"Period costume.","e2t":"Dönem kıyafeti."},{"w":"courier","tr":"kurye","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person or company that takes messages or packages","dt":"Mesaj veya paket taşıyan kişi veya şirket","e1":"We sent the documents by courier.","e1t":"Belgeleri kurye ile gönderdik.","e2":"Courier service.","e2t":"Kurye servisi."},{"w":"coverage","tr":"kapsama alanı / haber bülteni / sigorta teminatı","te":"Noun","tt":"İsim","de":"The amount or way that something is covered","dt":"Bir şeyin kapsanma miktarı veya biçimi","e1":"Live media coverage of the event.","e1t":"Olayın canlı medya takibi (haberi).","e2":"Mobile phone coverage.","e2t":"Cep telefonu kapsama alanı."},{"w":"coward","tr":"korkak","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has no courage","dt":"Cesareti olmayan kişi","e1":"Don't be such a coward!","e1t":"Bu kadar korkak olma!","e2":"He is a coward at heart.","e2t":"Özünde bir korkaktır."},{"w":"cozy / cosy","tr":"rahat / sıcak / samimi","te":"Adjective","tt":"Sıfat","de":"Warm, comfortable, and safe","dt":"Sıcak, rahat ve güvenli","e1":"A cozy little room.","e1t":"Rahat, küçük bir oda.","e2":"To have a cozy evening at home.","e2t":"Evde samimi (rahat) bir akşam geçirmek."},{"w":"cram","tr":"tıka basa doldurmak / (sınava) ineklemek","te":"Verb","tt":"Fiil","de":"To push a lot of things into a small space; to study hard","dt":"Küçük bir alana çok şey tıkıştırmak; çok ders çalışmak","e1":"He crammed all his clothes into the suitcase.","e1t":"Tüm kıyafetlerini valize tıka basa doldurdu.","e2":"She is cramming for her exams.","e2t":"Sınavlarına (hızla) hazırlanıyor (inekliyor)."},{"w":"craving","tr":"aşerme / güçlü istek / canı çekme","te":"Noun","tt":"İsim","de":"A strong feeling of wanting something","dt":"Bir şeyi çok güçlü bir şekilde isteme hissi","e1":"A craving for chocolate.","e1t":"Çikolata aşermesi (isteği).","e2":"Pregnant women often have unusual cravings.","e2t":"Hamile kadınların genellikle sıra dışı aşermeleri olur."},{"w":"credible","tr":"güvenilir / inanılır","te":"Adjective","tt":"Sıfat","de":"Able to be believed or trusted","dt":"İnanılabilen veya güvenilebilen","e1":"A credible witness.","e1t":"Güvenilir bir tanık.","e2":"There is no credible evidence.","e2t":"İnanılır (güvenilir) bir kanıt yok."},{"w":"creed","tr":"inanç / öğreti / amentü","te":"Noun","tt":"İsim","de":"A set of beliefs or principles","dt":"Bir dizi inanç veya ilke","e1":"People of all races and creeds.","e1t":"Tüm ırk ve inançlardan insanlar.","e2":"A political creed.","e2t":"Siyasi bir öğreti."},{"w":"critique","tr":"eleştirmek / eleştiri yazısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A detailed report or review of something","dt":"Bir şeyin detaylı raporu veya incelemesi","e1":"A critique of modern education.","e1t":"Modern eğitimin bir eleştirisi.","e2":"We need to critique the proposal.","e2t":"Öneriyi eleştirmeliyiz (incelemeliyiz)."},{"w":"crooked","tr":"eğri / yamuk / hilekar","te":"Adjective","tt":"Sıfat","de":"Not straight; or dishonest","dt":"Düz olmayan; veya dürüst olmayan","e1":"A crooked nose.","e1t":"Eğri bir burun.","e2":"A crooked businessman.","e2t":"Hilekar (yolsuz) bir iş adamı."},{"w":"crude","tr":"ham / kaba / basit","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"In a natural state; or simple and basic","dt":"Doğal halde; veya basit ve temel","e1":"Crude oil.","e1t":"Ham petrol.","e2":"A crude drawing.","e2t":"Basit (kaba taslak) bir çizim."},{"w":"crumble","tr":"ufalanmak / parçalanmak / çökmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break into small pieces","dt":"Küçük parçalara ayrılmak","e1":"The old walls are starting to crumble.","e1t":"Eski duvarlar ufalanmaya başlıyor.","e2":"The empire crumbled.","e2t":"İmparatorluk çöktü (parçalandı)."},{"w":"crunch","tr":"çatırtı / zor an / kriz / crunch yapmak","te":"Verb/Noun/Adj","tt":"To crush something loudly; or a difficult situation","de":"Bir şeyi sesli ezmek; veya zor durum","dt":"The crunch of dry leaves.","e1":"Kuru yaprakların çatırtısı.","e1t":"Economic crunch (crisis).","e2":"Ekonomik kriz (darboğaz).","e2t":""},{"w":"cumulative","tr":"kümülatif / birikimli","te":"Adjective","tt":"Sıfat","de":"Increasing by one addition after another","dt":"Birbiri ardına eklenerek artan","e1":"Cumulative effect.","e1t":"Birikimli (kümülatif) etki.","e2":"Cumulative score.","e2t":"Toplam (birikmiş) puan."},{"w":"curator","tr":"küratör / müze müdürü","te":"Noun","tt":"İsim","de":"A person in charge of a museum or art collection","dt":"Bir müze veya sanat koleksiyonundan sorumlu kişi","e1":"The curator of the National Gallery.","e1t":"Ulusal Galeri'nin küratörü.","e2":"Digital curator.","e2t":"Dijital içerik küratörü."},{"w":"curb","tr":"dizginlemek / kontrol altına almak / kaldırım kenarı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To control or limit something","dt":"Bir şeyi kontrol etmek veya sınırlamak","e1":"Measures to curb inflation.","e1t":"Enflasyonu dizginlemek için önlemler.","e2":"You should curb your temper.","e2t":"Öfkeni kontrol altına almalısın."},{"w":"curt","tr":"kısa ve kaba / kestirip atan","te":"Adjective","tt":"Sıfat","de":"Using few words in a way that seems rude","dt":"Kaba görünecek şekilde az kelime kullanan","e1":"A curt answer.","e1t":"Kısa ve kaba (kestirip atan) bir cevap.","e2":"He was very curt with me on the phone.","e2t":"Telefondaki tavrı çok sertti (kısaydı)."},{"w":"custody","tr":"velayet / gözaltı / koruma","te":"Noun","tt":"İsim","de":"The legal right to look after a child; or being in prison","dt":"Çocuğa bakma yasal hakkı; veya hapiste olma","e1":"The mother was granted custody of the children.","e1t":"Çocukların velayeti anneye verildi.","e2":"He is in police custody.","e2t":"Polis gözaltısında."},{"w":"customarily","tr":"geleneksel olarak / alışılageldiği üzere","te":"Adverb","tt":"Zarf","de":"In a way that follows custom","dt":"Geleneği takip eden bir şekilde","e1":"Customarily, the host speaks first.","e1t":"Geleneksel olarak, ev sahibi ilk konuşur.","e2":"It is customarily done this way.","e2t":"Alışılageldiği üzere bu şekilde yapılır."},{"w":"cylinder","tr":"silindir","te":"Noun","tt":"İsim","de":"A solid or hollow object with circular ends and straight sides","dt":"Dairesel uçları ve düz kenarları olan nesne","e1":"A gas cylinder.","e1t":"Gaz tüpü (silindiri).","e2":"Oxygen cylinder.","e2t":"Oksijen tüpü."},{"w":"cynical","tr":"alaycı / kötümser / kuşkucu","te":"Adjective","tt":"Sıfat","de":"Believing that people are only interested in themselves","dt":"İnsanların sadece kendilerini düşündüğüne inanan","e1":"He has a cynical view of politics.","e1t":"Siyasete karşı alaycı (kuşkucu) bir bakış açısı var.","e2":"A cynical smile.","e2t":"Alaycı bir gülümseme."},{"w":"dairy","tr":"süt ürünleri / mandıra","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Relating to milk or products made from milk","dt":"Süt veya sütten yapılan ürünlerle ilgili","e1":"Dairy products like cheese and butter.","e1t":"Peynir ve tereyağı gibi süt ürünleri.","e2":"I'm on a dairy","e2t":"free diet."},{"w":"dazzle","tr":"büyülemek / göz kamaştırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To surprise someone with style or skill; light blinding","dt":"Tarz veya beceriyle büyülemek; ışığın gözü alması","e1":"I was dazzled by her beauty.","e1t":"Onun güzelliğiyle büyülendim.","e2":"The car's headlights dazzled me.","e2t":"Arabanın farları gözümü kamaştırdı."},{"w":"deadly","tr":"ölümcül / çok sıkıcı","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Likely to cause death; or very","dt":"Ölüme neden olabilecek; veya çok","e1":"A deadly poison.","e1t":"Ölümcül bir zehir.","e2":"The lecture was deadly boring.","e2t":"Ders ölümüne (çok) sıkıcıydı."},{"w":"dealership","tr":"bayilik / acentelik","te":"Noun","tt":"İsim","de":"A company that has permission to sell a particular product","dt":"Belirli bir ürünü satma izni olan şirket","e1":"A car dealership.","e1t":"Araba bayisi.","e2":"He works at a local Ford dealership.","e2t":"Yerel bir Ford bayisinde çalışıyor."},{"w":"disastrous","tr":"felaket niteliğinde / korkunç","te":"Adjective","tt":"Sıfat","de":"Causing great harm, damage, or failure","dt":"Büyük zarar, hasar veya başarısızlığa neden olan","e1":"The war had a disastrous effect on the economy.","e1t":"Savaşın ekonomi üzerinde felaket niteliğinde bir etkisi oldu.","e2":"A disastrous harvest.","e2t":"Berbat (felaket) bir hasat."},{"w":"discard","tr":"atmak / ıskartaya çıkarmak / vazgeçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To throw something away because it is no longer useful","dt":"Artık yararlı olmadığı için bir şeyi atmak","e1":"Please discard all old files.","e1t":"Lütfen tüm eski dosyaları atın.","e2":"He discarded his jacket.","e2t":"Ceketini bir kenara attı."},{"w":"discern","tr":"ayırt etmek / fark etmek / sezmek","te":"Verb","tt":"Fiil","de":"To see, recognize, or understand something that is not clear","dt":"Net olmayan bir şeyi görmek, tanımak veya anlamak","e1":"It is difficult to discern the truth from his stories.","e1t":"Onun hikayelerinden gerçeği ayırt etmek zordur.","e2":"We could discern a faint light in the distance.","e2t":"Uzakta hafif bir ışık fark edebildik."},{"w":"discharge","tr":"tahliye etmek / boşaltmak / görevden çıkarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To allow someone to leave; or to send out liquid/gas","dt":"Birinin gitmesine izin vermek; veya sıvı/gaz salmak","e1":"He was discharged from the hospital yesterday.","e1t":"Dün hastaneden taburcu edildi (tahliye edildi).","e2":"The factory discharges toxic waste into the river.","e2t":"Fabrika nehre toksik atık boşaltıyor."},{"w":"discomfort","tr":"rahatsızlık / huzursuzluk","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of slight pain or worry","dt":"Hafif bir acı veya endişe hissi","e1":"These shoes are causing me great discomfort.","e1t":"Bu ayakkabılar bana büyük rahatsızlık veriyor.","e2":"Emotional discomfort.","e2t":"Duygusal huzursuzluk."},{"w":"disconnect","tr":"bağlantıyı kesmek / ayırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break a connection between two things","dt":"İki şey arasındaki bağlantıyı koparmak","e1":"The phone line has been disconnected.","e1t":"Telefon hattı kesildi.","e2":"There is a disconnect between his words and actions.","e2t":"Sözleri ve eylemleri arasında bir kopukluk var."},{"w":"discontinue","tr":"durdurmak / kesmek / son vermek","te":"Verb","tt":"Fiil","de":"To stop doing or providing something","dt":"Bir şeyi yapmayı veya sağlamayı bırakmak","e1":"The production of this model has been discontinued.","e1t":"Bu modelin üretimi durduruldu.","e2":"To discontinue a treatment.","e2t":"Bir tedaviyi sonlandırmak."},{"w":"discourage","tr":"cesaretini kırmak / vazgeçirmek","te":"Verb","tt":"Fiil","de":"To make someone feel less confident or enthusiastic","dt":"Birinin güvenini veya hevesini azaltmak","e1":"Don't let failure discourage you.","e1t":"Başarısızlığın cesaretini kırmasına izin verme.","e2":"Higher taxes may discourage investment.","e2t":"Yüksek vergiler yatırımı vazgeçirebilir (engelleyebilir)."},{"w":"discourse","tr":"söylem / söylev / tartışma","te":"Noun/Verb","tt":"İsim/Fiil","de":"Formal discussion of a subject in speech or writing","dt":"Bir konunun sözlü veya yazılı resmi tartışması","e1":"Political discourse in Turkey.","e1t":"Türkiye'deki siyasi söylem.","e2":"A discourse on education.","e2t":"Eğitim üzerine bir söylev (tartışma)."},{"w":"discrepancy","tr":"tutarsızlık / fark / uyuşmazlık","te":"Noun","tt":"İsim","de":"A difference between two things that should be the same","dt":"Aynı olması gereken iki şey arasındaki fark","e1":"There is a discrepancy between the two reports.","e1t":"İki rapor arasında bir tutarsızlık var.","e2":"Discrepancy in the budget.","e2t":"Bütçedeki uyuşmazlık."},{"w":"discretion","tr":"takdir yetkisi / sağduyu / gizlilik","te":"Noun","tt":"İsim","de":"The power to make decisions; or being careful in speech","dt":"Karar verme gücü; veya konuşmada/davranışta dikkat","e1":"The judge has the discretion to reduce the sentence.","e1t":"Hakim, cezayı indirme konusunda takdir yetkisine sahiptir.","e2":"You must use your own discretion.","e2t":"Kendi sağduyunuzu kullanmalısınız."},{"w":"discriminate","tr":"ayrım yapmak / ayırt etmek","te":"Verb","tt":"Fiil","de":"To treat someone unfairly; or to see the difference","dt":"Birine adaletsiz davranmak; veya farkı görmek","e1":"It is illegal to discriminate against people because of their race.","e1t":"İnsanlara ırklarından dolayı ayrımcılık yapmak yasadışıdır.","e2":"To discriminate between good and evil.","e2t":"İyiyle kötüyü ayırt etmek."},{"w":"disguise","tr":"kılık değiştirmek / gizlemek / maskelemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To change appearance to hide who you are","dt":"Kim olduğunuzu gizlemek için görünüşü değiştirmek","e1":"He disguised himself as a waiter.","e1t":"Kendini garson kılığında gizledi.","e2":"She couldn't disguise her disappointment.","e2t":"Hayal kırıklığını gizleyemedi."},{"w":"disintegrate","tr":"parçalanmak / dağılmak / ufalanmak","te":"Verb","tt":"Fiil","de":"To break into small pieces or to become weaker","dt":"Küçük parçalara ayrılmak veya zayıflayıp yok olmak","e1":"The spacecraft disintegrated on re","e1t":"entry.","e2":"Uzay aracı (atmosfere) girişte parçalandı.","e2t":"The ruling party is starting to disintegrate."},{"w":"dismantle","tr":"sökmek / parçalarına ayırmak","te":"Verb","tt":"Fiil","de":"To take a machine or structure apart","dt":"Bir makineyi veya yapıyı parçalarına ayırmak","e1":"He dismantled the engine to see what was wrong.","e1t":"Sorunun ne olduğunu görmek için motoru söktü.","e2":"To dismantle a system.","e2t":"Bir sistemi tasfiye etmek (sökmek)."},{"w":"dismay","tr":"hayal kırıklığına uğratmak / dehşete düşürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"A feeling of unhappiness and disappointment","dt":"Mutsuzluk ve hayal kırıklığı hissi","e1":"To our dismay, it started to rain.","e1t":"Hayal kırıklığımıza (üzüntümüze) rağmen yağmur yağmaya başladı.","e2":"The news dismayed the public.","e2t":"Haberler halkı dehşete düşürdü."},{"w":"dispatch","tr":"göndermek / sevketmek / rapor","te":"Verb/Noun","tt":"Fiil/İsim","de":"To send someone or something to a place","dt":"Birini veya bir şeyi bir yere göndermek","e1":"The rescue team was dispatched immediately.","e1t":"Kurtarma ekibi derhal sevk edildi.","e2":"News dispatch.","e2t":"Haber bülteni (raporu)."},{"w":"dispense","tr":"dağıtmak / hazırlayıp vermek (ilaç)","te":"Verb","tt":"Fiil","de":"To give out things to people","dt":"İnsanlara bir şeyler dağıtmak","e1":"The machine dispenses tickets.","e1t":"Makine bilet dağıtıyor.","e2":"A pharmacist dispenses medicine.","e2t":"Eczacı ilaç hazırlar (verir)."},{"w":"disperse","tr":"dağıtmak / yayılmak / dağılmak","te":"Verb","tt":"Fiil","de":"To move apart and go in different directions","dt":"Ayrılmak ve farklı yönlere gitmek","e1":"The police used water cannons to disperse the crowd.","e1t":"Polis kalabalığı dağıtmak için tazyikli su kullandı.","e2":"The seeds are dispersed by the wind.","e2t":"Tohumlar rüzgarla yayılır (dağılır)."},{"w":"disposal","tr":"imha etme / elden çıkarma / tasarruf","te":"Noun","tt":"İsim","de":"The act of getting rid of something","dt":"Bir şeyden kurtulma (atılması) eylemi","e1":"Waste disposal.","e1t":"Atık imhası.","e2":"I am at your disposal.","e2t":"Emrinizdeyim (tasarrufunuzdayım)."},{"w":"disrupt","tr":"bozmak / aksatmak / karışıklık çıkarmak","te":"Verb","tt":"Fiil","de":"To prevent something from continuing as usual","dt":"Bir şeyin her zamanki gibi devam etmesini engellemek","e1":"The strike disrupted the train service.","e1t":"Grev tren seferlerini aksattı.","e2":"New technology can disrupt traditional industries.","e2t":"Yeni teknoloji geleneksel endüstrileri bozabilir (değiştirebilir)."},{"w":"disruption","tr":"aksama / bozulma / kargaşa","te":"Noun","tt":"İsim","de":"A situation in which something cannot continue normally","dt":"Bir şeyin normal devam edemediği durum","e1":"Power disruption.","e1t":"Elektrik kesintisi (aksaması).","e2":"Serious disruption to traffic.","e2t":"Trafikte ciddi aksama."},{"w":"dissect","tr":"incelemek / kesip ayırmak (otopsi vb.)","te":"Verb","tt":"Fiil","de":"To cut open a body to study it; or to examine in detail","dt":"Bir vücudu incelemek için kesmek; veya detaylı incelemek","e1":"In biology class, we dissected a frog.","e1t":"Biyoloji dersinde bir kurbağayı kestik (inceledik).","e2":"To dissect an argument.","e2t":"Bir iddiayı en ince ayrıntısına kadar incelemek."},{"w":"disseminate","tr":"yaymak / dağıtmak (bilgi vb.)","te":"Verb","tt":"Fiil","de":"To spread information or ideas to many people","dt":"Bilgi veya fikirleri birçok insana yaymak","e1":"The internet is used to disseminate information quickly.","e1t":"İnternet, bilgiyi hızla yaymak için kullanılır.","e2":"To disseminate knowledge.","e2t":"Bilgiyi yaymak."},{"w":"dissent","tr":"muhalefet etmek / uyuşmamak / görüş ayrılığı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To disagree with other people's opinions","dt":"Diğer insanların görüşlerine katılmamak","e1":"There were several voices of dissent.","e1t":"Birkaç muhalif ses vardı.","e2":"To dissent from the majority view.","e2t":"Çoğunluk görüşüne muhalefet etmek."},{"w":"distinctive","tr":"ayırt edici / kendine has","te":"Adjective","tt":"Sıfat","de":"Having a quality that makes something different","dt":"Bir şeyi farklı kılan bir özelliğe sahip olan","e1":"This coffee has a very distinctive smell.","e1t":"Bu kahvenin çok ayırt edici (kendine has) bir kokusu var.","e2":"Distinctive features.","e2t":"Ayırt edici özellikler."},{"w":"distort","tr":"çarpıtmak / biçimini bozmak","te":"Verb","tt":"Fiil","de":"To change something so that it is no longer true or clear","dt":"Bir şeyi artık doğru veya net olmayacak şekilde değiştirmek","e1":"You are distorting the facts!","e1t":"Gerçekleri çarpıtıyorsun!","e2":"The speaker distorted the sound.","e2t":"Hoparlör sesi bozdu."},{"w":"distress","tr":"sıkıntı / keder / tehlike hali","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of extreme worry, sadness, or pain","dt":"Aşırı endişe, üzüntü veya acı hissi","e1":"Economic distress.","e1t":"Ekonomik sıkıntı.","e2":"A distress signal (SOS).","e2t":"İmdat (tehlike) sinyali."},{"w":"ditch","tr":"hendek / kurtulmak / başından savmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long narrow hole for water; or to get rid of something","dt":"Su için uzun dar delik; veya bir şeyden kurtulmak","e1":"The car slid into a ditch.","e1t":"Araba bir hendeğe kaydı.","e2":"He decided to ditch his old car.","e2t":"Eski arabasından kurtulmaya (başından savmaya) karar verdi."},{"w":"diversify","tr":"çeşitlendirmek","te":"Verb","tt":"Fiil","de":"To include many different types of things","dt":"Birçok farklı türü dahil etmek","e1":"The company is planning to diversify its products.","e1t":"Şirket ürünlerini çeşitlendirmeyi planlıyor.","e2":"We need to diversify our economy.","e2t":"Ekonomimizi çeşitlendirmeliyiz."},{"w":"diversion","tr":"yön değiştirme / oyalanma / trafik sapması","te":"Noun","tt":"İsim","de":"The act of changing the direction of something; or a pastime","dt":"Bir şeyin yönünü değiştirme eylemi; veya hobi","e1":"Traffic diversion.","e1t":"Trafik sapması (yol çalışması rotası).","e2":"A pleasant diversion.","e2t":"Hoş bir oyalanma (eğlence)."},{"w":"divert","tr":"yönünü değiştirmek / saptırmak / dikkatini dağıtmak","te":"Verb","tt":"Fiil","de":"To cause something or someone to change direction","dt":"Bir şeyin veya birinin yön değiştirmesini sağlamak","e1":"The flight was diverted to Istanbul.","e1t":"Uçuş İstanbul'a yönlendirildi.","e2":"To divert attention.","e2t":"Dikkatini dağıtmak (başka yöne çekmek)."},{"w":"divine","tr":"ilahi / kutsal / harika","te":"Adjective/Noun/Verb","tt":"Relating to a god; or very good","de":"Bir tanrı ile ilgili; veya çok iyi","dt":"Divine intervention.","e1":"İlahi müdahale.","e1t":"The food was simply divine!","e2":"Yemek tek kelimeyle harikaydı!","e2t":""},{"w":"dock","tr":"rıhtım / yanaşmak (gemi) / sanık kürsüsü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where ships stop; or the area for a prisoner in court","dt":"Gemilerin durduğu yer; veya mahkemedeki sanık alanı","e1":"The ship is in dock for repairs.","e1t":"Gemi tamir için rıhtımda.","e2":"The prisoner stood in the dock.","e2t":"Mahkum sanık kürsüsünde durdu."},{"w":"doctrine","tr":"öğreti / doktrin","te":"Noun","tt":"İsim","de":"A set of beliefs or principles, especially religious or political","dt":"İnanç veya ilkeler bütünü (dini veya siyasi)","e1":"Monroe Doctrine.","e1t":"Monroe Doktrini.","e2":"Religious doctrines.","e2t":"Dini öğretiler."},{"w":"documentation","tr":"dokümantasyon / belgeleme","te":"Noun","tt":"İsim","de":"Official papers that provide information or proof","dt":"Bilgi veya kanıt sağlayan resmi kağıtlar","e1":"Please provide the necessary documentation.","e1t":"Lütfen gerekli belgeleri (dokümantasyonu) sağlayın.","e2":"Software documentation.","e2t":"Yazılım dokümantasyonu."},{"w":"dodge","tr":"kaçınmak / kurtulmak / yana çekilmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To avoid someone or something by moving quickly","dt":"Hızla hareket ederek birinden veya bir şeyden kaçınmak","e1":"He dodged the ball.","e1t":"Topun gelmesinden kaçındı (yana çekildi).","e2":"To dodge taxes.","e2t":"Vergi kaçırmak."},{"w":"donor","tr":"bağışçı / verici","te":"Noun","tt":"İsim","de":"A person who gives money or part of their body","dt":"Para veya vücudunun bir parçasını veren kişi","e1":"Blood donor.","e1t":"Kan bağışçısı (vericisi).","e2":"Anonymous donor.","e2t":"Anonim (isimsiz) bağışçı."},{"w":"doom","tr":"kaderine terk etmek / kötü son / yıkım","te":"Verb/Noun","tt":"Fiil/İsim","de":"Death, destruction, or any very bad situation that cannot be avoided","dt":"Kaçınılamaz ölüm, yıkım veya çok kötü durum","e1":"The project was doomed to failure from the start.","e1t":"Proje en başından başarısızlığa mahkumdu.","e2":"Gloom and doom.","e2t":"Karamsarlık ve yıkım."},{"w":"doorway","tr":"kapı aralığı / giriş","te":"Noun","tt":"İsim","de":"The opening where a door is","dt":"Kapının olduğu açıklık","e1":"He stood in the doorway.","e1t":"Kapı aralığında durdu.","e2":"A doorway to success.","e2t":"Başarıya giden giriş."},{"w":"dormant","tr":"hareketsiz / uyku halinde","te":"Adjective","tt":"Sıfat","de":"Not active or growing now but able to become active later","dt":"Şu an aktif değil ama sonra aktif olabilen","e1":"A dormant volcano.","e1t":"Uyuyan (hareketsiz) yanardağ.","e2":"The seeds lie dormant in winter.","e2t":"Tohumlar kışın uyku halindedir."},{"w":"dose","tr":"doz / dozaj","te":"Noun/Verb","tt":"İsim/Fiil","de":"A measured amount of medicine","dt":"Ölçülmüş ilaç miktarı","e1":"A high dose of Vitamin C.","e1t":"Yüksek dozda C vitamini.","e2":"One dose every four hours.","e2t":"Her dört saatte bir doz."},{"w":"downfall","tr":"çöküş / yıkım","te":"Noun","tt":"İsim","de":"A sudden loss of power or success","dt":"Güç veya başarının ani kaybı","e1":"The scandal led to his downfall.","e1t":"Skandal onun çöküşüne (yıkımına) yol açtı.","e2":"The downfall of the empire.","e2t":"İmparatorluğun çöküşü."},{"w":"downgrade","tr":"düşürmek / alt modele geçirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To reduce someone or something to a lower rank or level","dt":"Birini veya bir şeyi daha düşük bir rütbe veya seviyeye indirmek","e1":"The credit rating was downgraded.","e1t":"Kredi notu düşürüldü.","e2":"To downgrade a system.","e2t":"Bir sistemi alt sürüme düşürmek."},{"w":"dozens","tr":"onlarca / çok sayıda","te":"Noun","tt":"İsim","de":"A group of twelve; or many","dt":"On ikili grup; veya çok sayıda","e1":"I have dozens of English books.","e1t":"Onlarca (çok sayıda) İngilizce kitabım var.","e2":"A dozen eggs.","e2t":"Bir düzine (12 adet) yumurta."},{"w":"drainage","tr":"su tahliyesi / drenaj","te":"Noun","tt":"İsim","de":"The system of water or waste flowing away","dt":"Suyun veya atığın akıp gitme sistemi","e1":"Poor drainage leads to flooding.","e1t":"Zayıf drenaj (tahliye) sellere yol açar.","e2":"Drainage system.","e2t":"Drenaj sistemi."},{"w":"dramatize","tr":"dramatize etmek / abartmak","te":"Verb","tt":"Fiil","de":"To turn a story into a play or movie; or to exaggerate","dt":"Bir hikayeyi oyuna çevirmek; veya abartmak","e1":"The book was dramatized for television.","e1t":"Kitap televizyon için dramatize edildi (uyarlandı).","e2":"Don't dramatize the situation.","e2t":"Durumu dramatize etme (abartma)."},{"w":"dread","tr":"büyük korku duyma / korkmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling of fear or worry","dt":"Güçlü korku veya endişe hissi","e1":"I dread to think what would happen.","e1t":"Ne olacağını düşünmekten korkuyorum (dehşete düşüyorum).","e2":"A feeling of dread.","e2t":"Bir dehşet (korku) hissi."},{"w":"dreadful","tr":"korkunç / çok kötü","te":"Adjective","tt":"Sıfat","de":"Very bad, unpleasant, or shocking","dt":"Çok kötü, nahoş veya şok edici","e1":"The weather was dreadful.","e1t":"Hava korkunçtu.","e2":"What a dreadful mistake!","e2t":"Ne korkunç bir hata!"},{"w":"dreary","tr":"kasvetli / sıkıcı / iç karartıcı","te":"Adjective","tt":"Sıfat","de":"Boring and making you feel unhappy","dt":"Sıkıcı ve mutsuz hissettiren","e1":"A dreary winter day.","e1t":"Kasvetli bir kış günü.","e2":"A dreary job.","e2t":"İç karartıcı bir iş."},{"w":"drizzle","tr":"çiselemek / çiseleme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To rain in very small, light drops","dt":"Çok küçük, hafif damlalar halinde yağmur yağması","e1":"It was beginning to drizzle as we left.","e1t":"Ayrılırken yağmur çiselemeye başlıyordu.","e2":"A light drizzle.","e2t":"Hafif bir çiseleme."},{"w":"duel","tr":"düello / kapışmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal fight between two people; or a struggle","dt":"İki kişi arasındaki resmi dövüş veya mücadele","e1":"He challenged his rival to a duel.","e1t":"Rakibini düelloya davet etti.","e2":"A verbal duel.","e2t":"Sözlü atışma (düello)."},{"w":"dumbfound","tr":"şoke etmek / ağzını açık bırakmak","te":"Verb","tt":"Fiil","de":"To surprise someone so much that they cannot speak","dt":"Birini konuşamayacak kadar çok şaşırtmak","e1":"The news of her resignation dumbfounded everyone.","e1t":"İstifa haberi herkesi şoke etti (ağzını açık bıraktı).","e2":"He stood there, dumbfounded.","e2t":"Şaşkınlıktan donakalmış bir halde orada durdu."},{"w":"duo","tr":"ikili","te":"Noun","tt":"İsim","de":"Two people, especially performers","dt":"İki kişi, özellikle performans sanatçıları","e1":"The famous comedy duo.","e1t":"Ünlü komedi ikilisi.","e2":"A dynamic duo.","e2t":"Dinamik bir ikili."},{"w":"duplicate","tr":"çoğaltmak / kopya / yedek","te":"Verb/Noun/Adj","tt":"To make an exact copy of something","de":"Bir şeyin tam bir kopyasını yapmak","dt":"Please duplicate this report for the meeting.","e1":"Lütfen bu raporu toplantı için çoğaltın.","e1t":"A duplicate key.","e2":"Yedek anahtar.","e2t":""},{"w":"durable","tr":"dayanıklı / sağlam","te":"Adjective","tt":"Sıfat","de":"Able to last a long time without breaking","dt":"Kırılmadan veya bozulmadan uzun süre dayanan","e1":"Durable consumer goods.","e1t":"Dayanıklı tüketim malları.","e2":"These tires are very durable.","e2t":"Bu lastikler çok dayanıklıdır."},{"w":"dusk","tr":"alacakaranlık / akşam karanlığı","te":"Noun","tt":"İsim","de":"The time before it gets dark in the evening","dt":"Akşam hava kararmadan önceki zaman","e1":"We arrived home just before dusk.","e1t":"Eve tam alacakaranlıktan önce vardık.","e2":"From dawn to dusk.","e2t":"Şafaktan gün batımına (alacakaranlığa) kadar."},{"w":"dutiful","tr":"görevine bağlı / itaatkar","te":"Adjective","tt":"Sıfat","de":"Doing everything that you should do","dt":"Yapmanız gereken her şeyi yapan","e1":"A dutiful daughter.","e1t":"Görevlerini yerine getiren (hayırlı) bir evlat.","e2":"Dutiful service.","e2t":"Sadıkane hizmet."},{"w":"dwell","tr":"ikamet etmek / yaşamak / üzerinde durmak","te":"Verb","tt":"Fiil","de":"To live in a specified place","dt":"Belirli bir yerde yaşamak","e1":"They dwell in the forest.","e1t":"Ormanda ikamet ediyorlar.","e2":"Don't dwell on the past.","e2t":"Geçmişin üzerinde (takılıp) kalma."},{"w":"dwellings","tr":"konutlar / meskenler","te":"Noun","tt":"İsim","de":"Houses or places to live in","dt":"Evler veya yaşanılan yerler","e1":"Ancient cliff dwellings.","e1t":"Antik kaya konutları.","e2":"Urban dwellings.","e2t":"Şehir konutları."},{"w":"eagerness","tr":"heves / isteklilik","te":"Noun","tt":"İsim","de":"The state of being very excited to do something","dt":"Bir şeyi yapma konusunda çok heyecanlı olma durumu","e1":"The children showed great eagerness to learn.","e1t":"Çocuklar öğrenmeye büyük bir heves gösterdi.","e2":"In his eagerness to finish...","e2t":"Bitirme hevesiyle..."},{"w":"earnest","tr":"ciddi / samimi / ağırbaşlı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Serious and sincere","dt":"Ciddi ve samimi","e1":"An earnest young man.","e1t":"Samimi ve ciddi genç bir adam.","e2":"The project began in earnest.","e2t":"Proje tam anlamıyla (ciddiyetle) başladı."},{"w":"eclipse","tr":"tutulma / gölgelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An occasion when the sun or moon is hidden","dt":"Güneşin veya ayın gizlendiği durum","e1":"Solar eclipse.","e1t":"Güneş tutulması.","e2":"His fame was eclipsed by his brother's.","e2t":"Şöhreti kardeşi tarafından gölgelendi."},{"w":"ecosystem","tr":"ekosistem","te":"Noun","tt":"İsim","de":"All the living things in an area and their environment","dt":"Bir bölgedeki tüm canlılar ve çevreleri","e1":"To protect the marine ecosystem.","e1t":"Deniz ekosistemini korumak.","e2":"The fragile ecosystem of the desert.","e2t":"Çölün hassas ekosistemi."},{"w":"edible","tr":"yenilebilir","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Safe to be eaten","dt":"Yenilmesi güvenli olan","e1":"Are these mushrooms edible?","e1t":"Bu mantarlar yenilebilir mi?","e2":"Edible plants.","e2t":"Yenilebilir bitkiler."},{"w":"editorial","tr":"editoryal yazı / başyazı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An article expressing the editor's opinion","dt":"Editörün görüşünü ifade eden makale","e1":"The newspaper's editorial on the election.","e1t":"Gazetenin seçim hakkındaki başyazısı.","e2":"Editorial staff.","e2t":"Yayın kurulu (editör kadrosu)."},{"w":"eerie","tr":"ürkütücü / esrarengiz","te":"Adjective","tt":"Sıfat","de":"Strange and frightening","dt":"Garip ve korkutucu","e1":"An eerie silence filled the room.","e1t":"Odayı ürkütücü bir sessizlik kapladı.","e2":"An eerie light.","e2t":"Esrarengiz bir ışık."},{"w":"effectiveness","tr":"etkililik / tesir","te":"Noun","tt":"İsim","de":"The ability to produce a desired result","dt":"İstenen sonucu üretme yeteneği","e1":"The effectiveness of the new law.","e1t":"Yeni yasanın etkililiği.","e2":"To improve cost effectiveness.","e2t":"Maliyet etkinliğini geliştirmek."},{"w":"elastic","tr":"esnek / lastikli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to return to its original shape","dt":"Orijinal şekline dönebilen","e1":"Rubber is elastic.","e1t":"Kauçuk esnektir.","e2":"Elastic potential energy.","e2t":"Esneklik potansiyel enerjisi."},{"w":"electoral","tr":"seçimle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to elections or electors","dt":"Seçimler veya seçmenlerle ilgili","e1":"Electoral system.","e1t":"Seçim sistemi.","e2":"Electoral reform.","e2t":"Seçim reformu."},{"w":"electrician","tr":"elektrikçi","te":"Noun","tt":"İsim","de":"A person who installs and repairs electrical equipment","dt":"Elektrikli ekipman kuran ve tamir eden kişi","e1":"We called an electrician to fix the wiring.","e1t":"Tesisatı tamir etmesi için bir elektrikçi çağırdık.","e2":"Master electrician.","e2t":"Usta elektrikçi."},{"w":"elongate","tr":"uzatmak / boyunu uzatmak","te":"Verb","tt":"Fiil","de":"To make something longer","dt":"Bir şeyi daha uzun yapmak","e1":"The cells began to elongate.","e1t":"Hücreler uzamaya başladı.","e2":"Exercises to elongate the muscles.","e2t":"Kasları uzatmak (esnetmek) için egzersizler."},{"w":"eloquent","tr":"etkili konuşan / hitabeti güçlü","te":"Adjective","tt":"Sıfat","de":"Expressing ideas clearly and persuasively","dt":"Fikirleri net ve ikna edici şekilde ifade eden","e1":"An eloquent speaker.","e1t":"Hitabeti güçlü bir konuşmacı.","e2":"Her speech was incredibly eloquent.","e2t":"Konuşması inanılmaz derecede etkileyiciydi."},{"w":"embankment","tr":"set / bent / dolgu yol","te":"Noun","tt":"İsim","de":"A wall of earth or stone to prevent flooding","dt":"Su baskınını önlemek için yapılan toprak veya taş duvar","e1":"A river embankment.","e1t":"Nehir bendi (seti).","e2":"A railway embankment.","e2t":"Demiryolu dolgusu."},{"w":"embark","tr":"(yolculuğa) çıkmak / başlamak / gemiye binmek","te":"Verb","tt":"Fiil","de":"To go onto a ship; or to start a new project","dt":"Gemiye binmek veya yeni bir projeye başlamak","e1":"They embarked on a world tour.","e1t":"Dünya turuna çıktılar.","e2":"We are about to embark on a new business venture.","e2t":"Yeni bir ticari girişime başlamak üzereyiz."},{"w":"embolden","tr":"cesaretlendirmek","te":"Verb","tt":"Fiil","de":"To give someone confidence","dt":"Birine güven vermek (cesaretlendirmek)","e1":"The success of the first game emboldened him.","e1t":"İlk oyunun başarısı onu cesaretlendirdi.","e2":"Emboldened by her support...","e2t":"Onun desteğiyle cesaret bularak..."},{"w":"embrace","tr":"kucaklamak / benimsemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hold someone tightly; or to accept an idea","dt":"Birini sıkıca tutmak; veya bir fikri kabul etmek","e1":"They embraced each other warmly.","e1t":"Birbirlerine sıcak bir şekilde sarıldılar.","e2":"To embrace new technology.","e2t":"Yeni teknolojiyi benimsemek."},{"w":"emergence","tr":"ortaya çıkış / belirme","te":"Noun","tt":"İsim","de":"The act of becoming known or visible","dt":"Bilinir veya görünür olma eylemi","e1":"The emergence of AI in education.","e1t":"Eğitimde yapay zekanın ortaya çıkışı.","e2":"The emergence of new leaders.","e2t":"Yeni liderlerin belirmesi."},{"w":"emigrant","tr":"göç eden kişi / muhacir","te":"Noun","tt":"İsim","de":"A person who leaves their own country to live in another","dt":"Başka bir ülkede yaşamak için kendi ülkesinden ayrılan kişi","e1":"Many emigrants moved to the US.","e1t":"Birçok göçmen ABD'ye taşındı.","e2":"Emigrant families.","e2t":"Göçmen aileler."},{"w":"emit","tr":"yaymak / salmak (ışık, gaz vb.)","te":"Verb","tt":"Fiil","de":"To send out light, sound, heat, or gas","dt":"Işık, ses, ısı veya gaz çıkarmak","e1":"The sun emits energy.","e1t":"Güneş enerji yayar.","e2":"Cars emit carbon dioxide.","e2t":"Arabalar karbondioksit salar."},{"w":"enact","tr":"yürürlüğe koymak / yasalaştırmak","te":"Verb","tt":"Fiil","de":"To make a law officially","dt":"Bir yasayı resmi olarak yapmak","e1":"The law was enacted last year.","e1t":"Yasa geçen yıl yürürlüğe kondu.","e2":"To enact a reform.","e2t":"Bir reformu yasalaştırmak."},{"w":"enclose","tr":"çevrelemek / içine koymak (zarf vb.)","te":"Verb","tt":"Fiil","de":"To surround with a wall; or to put inside an envelope","dt":"Bir duvarla çevrelemek; veya bir zarfın içine koymak","e1":"The garden is enclosed by a high fence.","e1t":"Bahçe yüksek bir çitle çevrilidir.","e2":"I enclose a check for $100.","e2t":"(Mektubun) İçine 100 dolarlık bir çek koyuyorum."},{"w":"endow","tr":"bağışlamak / (yetenek vb.) bahşetmek","te":"Verb","tt":"Fiil","de":"To give a large amount of money; or to provide with a quality","dt":"Büyük miktarda para bağışlamak; veya bir özellik kazandırmak","e1":"He endowed the hospital with a million dollars.","e1t":"Hastaneye bir milyon dolar bağışladı.","e2":"Endowed with natural talent.","e2t":"Doğal yetenekle donatılmış (bahşedilmiş)."},{"w":"engagement","tr":"bağlılık / nişanlılık / randevu / çarpışma","te":"Noun","tt":"İsim","de":"An agreement to marry; or involvement","dt":"Evlenme anlaşması; veya katılım/bağlılık","e1":"They announced their engagement.","e1t":"Nişanlandıklarını duyurdular.","e2":"Student engagement in the classroom.","e2t":"Öğrencilerin sınıftaki katılımı (bağlılığı)."},{"w":"engrave","tr":"kazımak / oymak","te":"Verb","tt":"Fiil","de":"To cut words or designs on a hard surface","dt":"Sert bir yüzeye kelime veya desen kazımak","e1":"His name was engraved on the trophy.","e1t":"Adı kupaya kazınmıştı.","e2":"An engraved invitation.","e2t":"İşlemeli (kazıma) bir davetiye."},{"w":"engulf","tr":"yutmak / içine çekmek / kaplamak","te":"Verb","tt":"Fiil","de":"To surround or cover something completely","dt":"Bir şeyi tamamen çevrelemek veya kaplamak","e1":"The flames engulfed the house.","e1t":"Alevler evi yuttu (kapladı).","e2":"The city was engulfed by the tide.","e2t":"Şehir sular altında kaldı (yutuldu)."},{"w":"enlightenment","tr":"aydınlanma","te":"Noun","tt":"İsim","de":"The process of gaining knowledge or understanding","dt":"Bilgi veya anlayış kazanma süreci","e1":"The Age of Enlightenment.","e1t":"Aydınlanma Çağı.","e2":"Spiritual enlightenment.","e2t":"Ruhani aydınlanma."},{"w":"enrich","tr":"zenginleştirmek","te":"Verb","tt":"Fiil","de":"To improve the quality of something","dt":"Bir şeyin kalitesini artırmak","e1":"This program will enrich your vocabulary.","e1t":"Bu program kelime hazinenizi zenginleştirecek.","e2":"To enrich the soil with minerals.","e2t":"Toprağı minerallerle zenginleştirmek."},{"w":"enroll / enrol","tr":"kaydolmak / kaydetmek","te":"Verb","tt":"Fiil","de":"To officially join a school or course","dt":"Bir okula veya kursa resmi olarak katılmak","e1":"I want to enroll in an English course.","e1t":"Bir İngilizce kursuna kaydolmak istiyorum.","e2":"They enrolled 500 new students.","e2t":"500 yeni öğrenci kaydettiler."},{"w":"ensue","tr":"ardından gelmek / sonuç olarak doğmak","te":"Verb","tt":"Fiil","de":"To happen after or as a result of something","dt":"Bir şeyden sonra veya onun bir sonucu olarak gerçekleşmek","e1":"A fight ensued after the match.","e1t":"Maçtan sonra bir kavga çıktı (ardından geldi).","e2":"The ensuing chaos.","e2t":"Ardından gelen (sonuç olarak doğan) kaos."},{"w":"entail","tr":"gerektirmek / yol açmak","te":"Verb","tt":"Fiil","de":"To involve something as a necessary part","dt":"Bir şeyi gerekli bir parça olarak içermek","e1":"The job entails a lot of travel.","e1t":"İş çok fazla seyahat gerektiriyor.","e2":"This decision entails certain risks.","e2t":"Bu karar belirli riskleri beraberinde getirir (gerektirir)."},{"w":"enterprise","tr":"girişim / işletme / atılganlık","te":"Noun","tt":"İsim","de":"A business or a difficult project","dt":"Bir işletme veya zorlu bir proje","e1":"A small business enterprise.","e1t":"Küçük bir ticari girişim.","e2":"Private enterprise.","e2t":"Özel teşebbüs."},{"w":"enthusiast","tr":"meraklı kişi / tutkun","te":"Noun","tt":"İsim","de":"A person who is very interested in a particular activity","dt":"Belirli bir faaliyetle çok ilgilenen kişi","e1":"A diving enthusiast.","e1t":"Dalış tutkunu (meraklısı).","e2":"Computer enthusiast.","e2t":"Bilgisayar meraklısı."},{"w":"entice","tr":"cezbetmek / aklını çelmek","te":"Verb","tt":"Fiil","de":"To persuade someone to do something by offering something nice","dt":"Güzel bir şey sunarak birini bir şey yapmaya ikna etmek","e1":"The smell of fresh bread enticed me into the shop.","e1t":"Taze ekmek kokusu beni dükkana çekti (cezbetti).","e2":"To entice customers with discounts.","e2t":"Müşterileri indirimlerle cezbetmek."},{"w":"envelop","tr":"sarmak / kuşatmak","te":"Verb","tt":"Fiil","de":"To cover or surround something completely","dt":"Bir şeyi tamamen kaplamak veya çevrelemek","e1":"Mist enveloped the mountains.","e1t":"Dağları sis kapladı (sardı).","e2":"Enveloped in silence.","e2t":"Sessizliğe bürünmüş."},{"w":"envision","tr":"hayal etmek / göz önünde canlandırmak","te":"Verb","tt":"Fiil","de":"To imagine something as a future possibility","dt":"Bir şeyi gelecek bir olasılık olarak hayal etmek","e1":"I envision a world without poverty.","e1t":"Yoksulluğun olmadığı bir dünya hayal ediyorum.","e2":"We envision a successful partnership.","e2t":"Başarılı bir ortaklık öngörüyoruz (canlandırıyoruz)."},{"w":"equate","tr":"eşitlemek / bir tutmak","te":"Verb","tt":"Fiil","de":"To consider one thing to be the same as another","dt":"Bir şeyi diğeriyle aynı (eşdeğer) saymak","e1":"You cannot equate money with happiness.","e1t":"Parayı mutlulukla bir tutamazsınız (eşitleyemezsiniz).","e2":"Most people equate wealth with success.","e2t":"Çoğu insan serveti başarıyla eş tutar."},{"w":"equilibrium","tr":"denge","te":"Noun","tt":"İsim","de":"A state in which opposing forces are balanced","dt":"Karşıt güçlerin dengelendiği durum","e1":"The supply and demand are in equilibrium.","e1t":"Arz ve talep dengede.","e2":"To maintain your emotional equilibrium.","e2t":"Duygusal dengenizi korumak."},{"w":"eradicate","tr":"yok etmek / kökünü kazımak","te":"Verb","tt":"Fiil","de":"To get rid of something completely","dt":"Bir şeyi tamamen ortadan kaldırmak","e1":"Smallpox has been eradicated.","e1t":"Çiçek hastalığının kökü kazındı (yok edildi).","e2":"To eradicate poverty.","e2t":"Yoksulluğu yok etmek."},{"w":"errand","tr":"ayak işi / getir götür","te":"Noun","tt":"İsim","de":"A short journey to do a specific job","dt":"Belirli bir işi yapmak için yapılan kısa yolculuk","e1":"I have some errands to run.","e1t":"Yapmam gereken bazı ayak işleri (getir götür) var.","e2":"To go on an errand.","e2t":"Bir iş için dışarı çıkmak."},{"w":"escalate","tr":"tırmanmak (kriz vb.) / kızışmak / yükselmek","te":"Verb","tt":"Fiil","de":"To become or make something more serious or intense","dt":"Bir şeyi daha ciddi veya şiddetli hale getirmek/gelmek","e1":"The protest began to escalate into a riot.","e1t":"Protesto bir ayaklanmaya dönüşmeye (tırmanmaya) başladı.","e2":"To escalate the conflict.","e2t":"Çatışmayı kızıştırmak."},{"w":"escort","tr":"eşlik etmek / korumak / refakatçi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go with someone to protect or guide them","dt":"Birine korumak veya yol göstermek için eşlik etmek","e1":"Police cars escorted the president's limo.","e1t":"Polis arabaları başkanın limuzinine eşlik etti.","e2":"A security escort.","e2t":"Güvenlik refakatçisi."},{"w":"esteem","tr":"saygı göstermek / değer vermek / itibar","te":"Noun/Verb","tt":"İsim/Fiil","de":"Respect and admiration for someone","dt":"Birine duyulan saygı ve hayranlık","e1":"He is held in high esteem by his colleagues.","e1t":"Meslektaşları tarafından büyük saygı görür (itibarı yüksektir).","e2":"Self","e2t":"esteem."},{"w":"eternal","tr":"ebedi / sonsuz","te":"Adjective","tt":"Sıfat","de":"Lasting forever or for a very long time","dt":"Sonsuza dek veya çok uzun süre devam eden","e1":"Eternal life.","e1t":"Ölümsüz (ebedi) yaşam.","e2":"I am tired of their eternal arguments.","e2t":"Onların bitmek bilmeyen (sonsuz) tartışmalarından bıktım."},{"w":"ethic","tr":"etik ilke / ahlak kuralı","te":"Noun","tt":"İsim","de":"A system of moral principles","dt":"Ahlaki ilkeler sistemi","e1":"A strong work ethic.","e1t":"Güçlü bir iş ahlakı.","e2":"Medical ethics.","e2t":"Tıp etiği."},{"w":"evacuate","tr":"tahliye etmek / boşaltmak","te":"Verb","tt":"Fiil","de":"To move people from a dangerous place to safety","dt":"İnsanları tehlikeli bir yerden güvenli bir yere taşımak","e1":"The building was evacuated due to a bomb threat.","e1t":"Bina bomba tehdidi nedeniyle tahliye edildi.","e2":"To evacuate a city.","e2t":"Bir şehri boşaltmak."},{"w":"evade","tr":"kaçınmak / sakınmak / (sorudan) kaçmak","te":"Verb","tt":"Fiil","de":"To avoid or escape from someone or something","dt":"Birinden veya bir şeyden kaçınmak/kurtulmak","e1":"He managed to evade the police.","e1t":"Polisten kaçmayı başardı.","e2":"To evade taxes.","e2t":"Vergi kaçırmak."},{"w":"eventual","tr":"nihai / sonunda olan","te":"Adjective","tt":"Sıfat","de":"Happening at the end of a process","dt":"Bir sürecin sonunda gerçekleşen","e1":"The eventual success of the project.","e1t":"Projenin nihai başarısı.","e2":"Her eventual recovery.","e2t":"Onun sonundaki (nihai) iyileşmesi."},{"w":"evoke","tr":"çağrıştırmak / uyandırmak (duygu, anı)","te":"Verb","tt":"Fiil","de":"To make someone remember something or feel an emotion","dt":"Birine bir şeyi hatırlatmak veya bir duyguyu hissettirmek","e1":"The smell of the sea evoked memories of his childhood.","e1t":"Deniz kokusu çocukluk anılarını çağrıştırdı.","e2":"To evoke a response.","e2t":"Bir tepki uyandırmak."},{"w":"exalt","tr":"yüceltmek / övmek","te":"Verb","tt":"Fiil","de":"To praise someone or something very much","dt":"Birini veya bir şeyi çok fazla övmek","e1":"He was exalted as a national hero.","e1t":"Ulusal bir kahraman olarak yüceltildi.","e2":"To exalt the importance of education.","e2t":"Eğitimin önemini yüceltmek."},{"w":"excavate","tr":"kazmak / (tarihi eseri) kazıyla çıkarmak","te":"Verb","tt":"Fiil","de":"To remove earth carefully to find ancient objects","dt":"Antik nesneleri bulmak için toprağı dikkatle kazmak","e1":"Archaeologists are excavating the site.","e1t":"Arkeologlar alanı kazıyorlar.","e2":"To excavate a tunnel.","e2t":"Tünel kazmak."},{"w":"exceedingly","tr":"aşırı derecede / son derece","te":"Adverb","tt":"Zarf","de":"To a very great degree","dt":"Çok büyük bir derecede","e1":"The task was exceedingly difficult.","e1t":"Görev aşırı derecede zordu.","e2":"Exceedingly kind.","e2t":"Son derece nazik."},{"w":"excerpt","tr":"alıntı / parça (kitap/müzik)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short part taken from a book, speech, or movie","dt":"Kitap, konuşma veya filmden alınan kısa bir bölüm","e1":"He read an excerpt from his new novel.","e1t":"Yeni romanından bir alıntı okudu.","e2":"Musical excerpt.","e2t":"Müzikal parça."},{"w":"excessive","tr":"aşırı / fazlası","te":"Adjective","tt":"Sıfat","de":"Too much or more than is reasonable","dt":"Makul olandan çok daha fazla","e1":"Excessive noise.","e1t":"Aşırı gürültü.","e2":"Excessive spending.","e2t":"Aşırı harcama."},{"w":"excursion","tr":"gezinti / kısa yolculuk","te":"Noun","tt":"İsim","de":"A short journey usually made for pleasure","dt":"Genellikle zevk için yapılan kısa yolculuk","e1":"A day excursion to the mountains.","e1t":"Dağlara bir günlük gezinti.","e2":"We went on an excursion to Efes.","e2t":"Efes'e bir geziye gittik."},{"w":"execution","tr":"yürütme / uygulama / idam","te":"Noun","tt":"İsim","de":"The act of doing something; or putting someone to death","dt":"Bir şeyi yapma eylemi; veya birini idam etme","e1":"The execution of the plan.","e1t":"Planın uygulanması (yürütülmesi).","e2":"Public execution.","e2t":"Aleni idam."},{"w":"exemplary","tr":"örnek alınacak / ibretlik","te":"Adjective","tt":"Sıfat","de":"Very good and serving as an example","dt":"Çok iyi ve örnek teşkil eden","e1":"His behavior has been exemplary.","e1t":"Davranışı örnek alınacak düzeydeydi.","e2":"Exemplary punishment.","e2t":"İbretlik ceza."},{"w":"exert","tr":"çaba göstermek / (güç) kullanmak","te":"Verb","tt":"Fiil","de":"To use power or influence to make something happen","dt":"Bir şeyin olması için güç veya nüfuz kullanmak","e1":"You need to exert more effort.","e1t":"Daha fazla çaba göstermelisin.","e2":"To exert pressure on someone.","e2t":"Birine baskı uygulamak."},{"w":"exhaustive","tr":"kapsamlı / detaylı / yorucu","te":"Adjective","tt":"Sıfat","de":"Complete and including everything","dt":"Eksiksiz ve her şeyi içeren","e1":"An exhaustive study.","e1t":"Kapsamlı (detaylı) bir çalışma.","e2":"Exhaustive research.","e2t":"Çok detaylı araştırma."},{"w":"expedite","tr":"hızlandırmak / çabuklaştırmak","te":"Verb","tt":"Fiil","de":"To make a process happen more quickly","dt":"Bir sürecin daha hızlı gerçekleşmesini sağlamak","e1":"We need to expedite the delivery.","e1t":"Teslimatı hızlandırmalıyız.","e2":"To expedite a legal process.","e2t":"Yasal bir süreci çabuklaştırmak."},{"w":"expel","tr":"kovmak / (okuldan) atmak / nefes vermek","te":"Verb","tt":"Fiil","de":"To force someone to leave a school or country","dt":"Birini okuldan veya ülkeden ayrılmaya zorlamak","e1":"He was expelled from school for fighting.","e1t":"Kavga ettiği için okuldan atıldı.","e2":"To expel air from the lungs.","e2t":"Akciğerlerden havayı dışarı atmak."},{"w":"expenditure","tr":"harcama / masraf","te":"Noun","tt":"İsim","de":"An amount of money spent","dt":"Harcanan para miktarı","e1":"Government expenditure on education.","e1t":"Hükümetin eğitime yaptığı harcama.","e2":"Total expenditure.","e2t":"Toplam masraf."},{"w":"expire","tr":"süresinin dolması / (vade) bitmek","te":"Verb","tt":"Fiil","de":"To come to an end (for a document or period)","dt":"(Belge veya dönem için) sona ermek","e1":"My passport expires next month.","e1t":"Pasaportumun süresi gelecek ay doluyor.","e2":"The contract has expired.","e2t":"Sözleşmenin vadesi bitti."},{"w":"explicit","tr":"açık / net / belirgin","te":"Adjective","tt":"Sıfat","de":"Clear and exact, with no doubt","dt":"Şüpheye yer bırakmayan, net ve kesin","e1":"He gave me explicit instructions.","e1t":"Bana çok açık (net) talimatlar verdi.","e2":"Explicit content.","e2t":"Belirgin (açık) içerik."},{"w":"exploration","tr":"keşif / araştırma","te":"Noun","tt":"İsim","de":"The act of traveling to a place to learn about it","dt":"Bir yeri öğrenmek için oraya seyahat etme eylemi","e1":"Space exploration.","e1t":"Uzay keşfi.","e2":"Oil exploration.","e2t":"Petrol arama (keşfi)."},{"w":"explorer","tr":"kaşif","te":"Noun","tt":"İsim","de":"A person who travels to unknown places","dt":"Bilinmeyen yerlere seyahat eden kişi","e1":"Christopher Columbus was a famous explorer.","e1t":"Kristof Kolomb ünlü bir kaşifti.","e2":"Polar explorer.","e2t":"Kutup kaşifi."},{"w":"exposure","tr":"maruz kalma / ifşa / pozlama","te":"Noun","tt":"İsim","de":"The state of being unprotected from something","dt":"Bir şeye karşı korumasız olma durumu","e1":"Prolonged exposure to the sun.","e1t":"Güneşe uzun süre maruz kalma.","e2":"Exposure of a secret.","e2t":"Bir sırrın ifşası."},{"w":"expressway","tr":"otoyol / sürat yolu","te":"Noun","tt":"İsim","de":"A wide road for fast","dt":"moving traffic","e1":"Hızlı trafik için geniş yol","e1t":"We took the expressway to Istanbul.","e2":"İstanbul'a gitmek için otoyolu kullandık.","e2t":"Toll expressway."},{"w":"exquisite","tr":"çok güzel / nefis / zarif","te":"Adjective","tt":"Sıfat","de":"Very beautiful and delicate","dt":"Çok güzel ve narin","e1":"An exquisite piece of jewelry.","e1t":"Çok zarif (nefis) bir mücevher.","e2":"The food was exquisite.","e2t":"Yemek harikaydı."},{"w":"extinct","tr":"nesli tükenmiş / sönmüş","te":"Adjective","tt":"Sıfat","de":"(Of an animal) no longer existing; or (of a volcano) not active","dt":"(Hayvan için) artık var olmayan; veya (yanardağ için) aktif olmayan","e1":"Dinosaurs are extinct.","e1t":"Dinozorların nesli tükenmiştir.","e2":"An extinct volcano.","e2t":"Sönmüş bir yanardağ."},{"w":"extinguish","tr":"söndürmek / yok etmek","te":"Verb","tt":"Fiil","de":"To stop a fire from burning","dt":"Ateşin yanmasını durdurmak","e1":"Please extinguish your cigarettes.","e1t":"Lütfen sigaralarınızı söndürün.","e2":"To extinguish all hope.","e2t":"Tüm umutları yok etmek."},{"w":"extract","tr":"çıkarmak / özet / özüt","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull out; or to take a part of something","dt":"Çekip çıkarmak; veya bir şeyin parçasını/özünü almak","e1":"The dentist had to extract the tooth.","e1t":"Diş hekimi dişi çekmek (çıkarmak) zorunda kaldı.","e2":"Vanilla extract.","e2t":"Vanilya özütü."},{"w":"extravagant","tr":"savurgan / aşırı / müsrif","te":"Adjective","tt":"Sıfat","de":"Spending too much money or using too much of something","dt":"Çok fazla para harcayan veya bir şeyi çok fazla kullanan","e1":"An extravagant lifestyle.","e1t":"Savurgan (müsrif) bir yaşam tarzı.","e2":"Extravagant gifts.","e2t":"Aşırı (pahalı) hediyeler."},{"w":"eyesight","tr":"görme yetisi / görüş","te":"Noun","tt":"İsim","de":"The ability to see","dt":"Görme yeteneği","e1":"He has very poor eyesight.","e1t":"Görme yetisi çok zayıf.","e2":"To lose one's eyesight.","e2t":"Görme yetisini kaybetmek."},{"w":"fabricate","tr":"uydurmak / imal etmek / üretmek","te":"Verb","tt":"Fiil","de":"To invent false information; or to produce goods","dt":"Yanlış bilgi uydurmak; veya mal üretmek","e1":"He fabricated a story to explain his absence.","e1t":"Yokluğunu açıklamak için bir hikaye uydurdu.","e2":"The parts are fabricated in Germany.","e2t":"Parçalar Almanya'da imal ediliyor."},{"w":"fabulous","tr":"harika / efsanevi / muhteşem","te":"Adjective","tt":"Sıfat","de":"Very good or excellent; or related to fables","dt":"Çok iyi veya mükemmel; veya efsanelerle ilgili","e1":"You look fabulous!","e1t":"Harika görünüyorsun!","e2":"A fabulous sum of money.","e2t":"Muazzam (hayal edilemez) bir para miktarı."},{"w":"faction","tr":"hizip / grup / klik","te":"Noun","tt":"İsim","de":"A small group within a larger group","dt":"Daha büyük bir grup içindeki küçük grup","e1":"Different factions within the political party.","e1t":"Siyasi parti içindeki farklı hizipler (gruplar).","e2":"Rival factions.","e2t":"Rakip hizipler."},{"w":"fallacy","tr":"yanlış inanç / safsata / yanılgı","te":"Noun","tt":"İsim","de":"A false idea that many people believe is true","dt":"Birçok insanın doğru olduğuna inandığı yanlış fikir","e1":"It is a common fallacy that...","e1t":"... olduğu yaygın bir yanılgıdır.","e2":"Logical fallacy.","e2t":"Mantıksal safsata."},{"w":"fascinate","tr":"büyülemek / hayran bırakmak","te":"Verb","tt":"Fiil","de":"To interest someone very much","dt":"Birinin çok ilgisini çekmek","e1":"Space exploration fascinates me.","e1t":"Uzay keşfi beni büyülüyor.","e2":"He was fascinated by her stories.","e2t":"Onun hikayelerinden çok etkilendi (hayran kaldı)."},{"w":"fascination","tr":"büyülenme / hayranlık / cazibe","te":"Noun","tt":"İsim","de":"The state of being very interested in something","dt":"Bir şeye çok ilgi duyma durumu","e1":"Her fascination with butterflies.","e1t":"Onun kelebeklere olan hayranlığı.","e2":"A place of eternal fascination.","e2t":"Sonsuz cazibeye sahip bir yer."},{"w":"feast","tr":"ziyafet / bayram / şölen","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large meal, typically a celebratory one","dt":"Genellikle kutlama amaçlı büyük yemek","e1":"A wedding feast.","e1t":"Düğün ziyafeti.","e2":"We feasted on turkey.","e2t":"Hindiyle ziyafet çektik."},{"w":"feat","tr":"başarı / ustalık / beceri","te":"Noun","tt":"İsim","de":"Something difficult that needs a lot of skill or luck","dt":"Çok beceri veya şans gerektiren zor bir şey","e1":"A remarkable feat of engineering.","e1t":"Dikkat çekici bir mühendislik başarısı.","e2":"No mean feat (a difficult task).","e2t":"Azımsanmayacak bir başarı (zor iş)."},{"w":"federation","tr":"federasyon","te":"Noun","tt":"İsim","de":"A group of states or organizations with a central government","dt":"Merkezi bir hükümete sahip devletler veya kuruluşlar grubu","e1":"The Russian Federation.","e1t":"Rusya Federasyonu.","e2":"International Football Federation (FIFA).","e2t":"Uluslararası Futbol Federasyonu."},{"w":"feeble","tr":"güçsüz / zayıf / cılız","te":"Adjective","tt":"Sıfat","de":"Very weak","dt":"Çok zayıf","e1":"A feeble old man.","e1t":"Güçsüz bir yaşlı adam.","e2":"A feeble excuse.","e2t":"Cılız (ikna edici olmayan) bir bahane."},{"w":"feign","tr":"taklit etmek / numara yapmak /","te":"miş gibi yapmak","tt":"Verb","de":"Fiil","dt":"To pretend to feel something","e1":"Bir şeyi hissediyormuş gibi davranmak","e1t":"He feigned illness to stay home.","e2":"Evde kalmak için hastalık numarası yaptı (hasta gibi davrandı).","e2t":"To feign surprise."},{"w":"fertile","tr":"verimli / bereketli / üretken","te":"Adjective","tt":"Sıfat","de":"(Of land) able to produce many plants","dt":"(Toprak için) birçok bitki üretebilen","e1":"Fertile soil.","e1t":"Verimli toprak.","e2":"A fertile imagination.","e2t":"Üretken (zengin) bir hayal gücü."},{"w":"fertilizer","tr":"gübre","te":"Noun","tt":"İsim","de":"A substance added to soil to make it more fertile","dt":"Toprağı daha verimli hale getirmek için eklenen madde","e1":"Artificial fertilizer.","e1t":"Yapay gübre.","e2":"To spread fertilizer.","e2t":"Gübre serpmek."},{"w":"fervent","tr":"ateşli / tutkulu / coşkulu","te":"Adjective","tt":"Sıfat","de":"Showing strong and sincere feelings","dt":"Güçlü ve samimi duygular gösteren","e1":"A fervent supporter of the cause.","e1t":"Davanın ateşli (tutkulu) bir destekçisi.","e2":"Fervent prayer.","e2t":"Coşkulu dua."},{"w":"feud","tr":"husumet / kan davası / çekişme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long and bitter argument between two groups","dt":"İki grup arasındaki uzun ve acı tartışma","e1":"A family feud.","e1t":"Aile husumeti (kavgası).","e2":"A long","e2t":"running feud between the two tribes."},{"w":"feverish","tr":"ateşli / telaşlı / heyecanlı","te":"Adjective","tt":"Sıfat","de":"Having a high body temperature; or very excited","dt":"Vücut ısısı yüksek; veya çok heyecanlı/telaşlı","e1":"A feverish child.","e1t":"Ateşli bir çocuk.","e2":"Feverish activity.","e2t":"Telaşlı (yoğun) faaliyet."},{"w":"filmmaker","tr":"film yapımcısı / yönetmen","te":"Noun","tt":"İsim","de":"A person who makes movies","dt":"Film yapan kişi","e1":"He is an award","e1t":"winning independent filmmaker.","e2":"O, ödüllü bağımsız bir film yapımcısıdır.","e2t":"Documentary filmmaker."},{"w":"finesse","tr":"ustalık / incelik / beceri","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great skill or style in handling a situation","dt":"Bir durumu idare etmede büyük beceri veya tarz","e1":"He handled the difficult interview with great finesse.","e1t":"Zorlu mülakatı büyük bir ustalıkla (incelikle) idare etti.","e2":"To finesse a deal.","e2t":"Bir anlaşmayı ustalıkla bitirmek."},{"w":"firmament","tr":"gök kubbe / gökyüzü","te":"Noun","tt":"İsim","de":"The sky or the heavens (literary)","dt":"Gökyüzü veya sema (edebi)","e1":"The stars sparkled in the firmament.","e1t":"Yıldızlar gök kubbede parlıyordu.","e2":"A new star in the political firmament.","e2t":"Siyasi gökyüzünde (arenada) yeni bir yıldız."},{"w":"firsthand","tr":"birinci elden / doğrudan","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Experienced directly, not from others","dt":"Başkalarından değil, doğrudan deneyimlenen","e1":"I have firsthand experience of the war.","e1t":"Savaşla ilgili birinci elden tecrübem var.","e2":"To see the effects firsthand.","e2t":"Etkileri doğrudan (kendi gözüyle) görmek."},{"w":"flair","tr":"yetenek / sezgi / tarz","te":"Noun","tt":"İsim","de":"A natural ability to do something well","dt":"Bir şeyi iyi yapma konusunda doğal yetenek","e1":"He has a flair for languages.","e1t":"Dillere karşı doğal bir yeteneği (yatkınlığı) var.","e2":"She dresses with flair.","e2t":"Şık bir tarzla giyinir."},{"w":"flank","tr":"yan taraf / kanat / böğür","te":"Noun/Verb","tt":"İsim/Fiil","de":"The side of something; or to be at the side of","dt":"Bir şeyin yan tarafı; veya yanında yer almak","e1":"The mountains flanked the valley.","e1t":"Dağlar vadinin iki yanını çevreliyordu.","e2":"They attacked the enemy's left flank.","e2t":"Düşmanın sol kanadına saldırdılar."},{"w":"flap","tr":"kanat çırpmak / dalgalanmak / kapak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move up and down (wings); or a moving part","dt":"Kanat çırpmak; veya hareketli parça/kapak","e1":"The bird flapped its wings and flew away.","e1t":"Kuş kanatlarını çırptı ve uçup gitti.","e2":"An envelope flap.","e2t":"Zarf kapağı."},{"w":"flare","tr":"parlamak / (öfke) patlamak / işaret fişeği","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden bright light; or a sudden expression of anger","dt":"Ani parlak ışık; veya ani öfke patlaması","e1":"The match flared in the darkness.","e1t":"Karanlıkta kibrit parladı.","e2":"To fire a signal flare.","e2t":"İşaret fişeği fırlatmak."},{"w":"flatter","tr":"pohpohlamak / yağ çekmek / (kıyafet) yakışmak","te":"Verb","tt":"Fiil","de":"To praise someone too much to please them","dt":"Birini memnun etmek için aşırı övmek","e1":"Are you trying to flatter me?","e1t":"Beni pohpohlamaya mı çalışıyorsun?","e2":"That dress really flatters you.","e2t":"O elbise sana gerçekten çok yakışmış."},{"w":"flaw","tr":"kusur / hata / çatlak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small fault or mistake that makes something less perfect","dt":"Bir şeyi daha az mükemmel kılan küçük hata veya kusur","e1":"There is a flaw in your logic.","e1t":"Mantığında bir hata (kusur) var.","e2":"A character flaw.","e2t":"Karakter kusuru."},{"w":"flawless","tr":"kusursuz / hatasız","te":"Adjective","tt":"Sıfat","de":"Perfect, without any mistakes","dt":"Mükemmel, hiç hatası olmayan","e1":"Her English is flawless.","e1t":"Onun İngilizcesi kusursuzdur.","e2":"A flawless performance.","e2t":"Hatasız bir performans."},{"w":"flicker","tr":"titrek yanmak / pır pır etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shine with a light that is not steady","dt":"Sabit olmayan bir ışıkla parlamak","e1":"The candle flickered in the wind.","e1t":"Mum rüzgarda titredi (titrek yandı).","e2":"A flicker of hope.","e2t":"Bir umut ışığı (pırıltısı)."},{"w":"fling","tr":"savurmak / fırlatmak / kısa süreli ilişki","te":"Verb/Noun","tt":"Fiil/İsim","de":"To throw something with a lot of force","dt":"Bir şeyi büyük bir güçle fırlatmak","e1":"He flung the door open.","e1t":"Kapıyı savurarak açtı.","e2":"To have a summer fling.","e2t":"Yaz aşkı (kısa süreli ilişki) yaşamak."},{"w":"flock","tr":"sürü / üşüşmek / akın etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of birds or sheep; or to gather","dt":"Kuş veya koyun sürüsü; veya toplanmak/akın etmek","e1":"A flock of seagulls.","e1t":"Martı sürüsü.","e2":"Tourists flocked to the city.","e2t":"Turistler şehre akın etti."},{"w":"floodgate","tr":"taşkın kapısı / baraj kapağı","te":"Noun","tt":"İsim","de":"A gate that controls the flow of water","dt":"Su akışını kontrol eden kapak","e1":"The decision opened the floodgates for more lawsuits.","e1t":"Karar, daha fazla davanın önünü açtı (baraj kapaklarını açtı).","e2":"To close the floodgates.","e2t":"Taşkın kapaklarını kapatmak."},{"w":"fluent","tr":"akıcı","te":"Adjective","tt":"Sıfat","de":"Able to speak or write a language easily","dt":"Bir dili kolayca konuşabilen veya yazabilen","e1":"He is fluent in Turkish and English.","e1t":"Türkçe ve İngilizcede akıcıdır.","e2":"She speaks fluent French.","e2t":"Akıcı Fransızca konuşur."},{"w":"fluff","tr":"kabartmak / tüy / hav","te":"Noun/Verb","tt":"İsim/Fiil","de":"Soft, light fibers or fur","dt":"Yumuşak, hafif lifler veya tüyler","e1":"Shake the pillow to fluff it up.","e1t":"Kabartmak için yastığı salla.","e2":"There is some fluff on your coat.","e2t":"Paltonun üzerinde biraz hav (tüy) var."},{"w":"flutter","tr":"kanat çırpmak / pır pır etmek / heyecanlanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fly with quick light movements","dt":"Hızlı ve hafif hareketlerle uçmak","e1":"The butterfly fluttered its wings.","e1t":"Kelebek kanatlarını çırptı.","e2":"My heart began to flutter.","e2t":"Kalbim pır pır etmeye (hızlı çarpmaya) başladı."},{"w":"foe","tr":"düşman","te":"Noun","tt":"İsim","de":"An enemy (literary/formal)","dt":"Düşman (edebi/resmi)","e1":"Are you friend or foe?","e1t":"Dost musun düşman mı?","e2":"A formidable foe.","e2t":"Dişli (korkutucu) bir düşman."},{"w":"foil","tr":"başarısızlığa uğratmak / folyo / engel olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To prevent someone from succeeding","dt":"Birinin başarılı olmasını engellemek","e1":"The police foiled the robbery attempt.","e1t":"Polis soygun girişimini boşa çıkardı (engelledi).","e2":"Aluminum foil.","e2t":"Alüminyum folyo."},{"w":"foliage","tr":"yeşillik / bitki yaprakları","te":"Noun","tt":"İsim","de":"The leaves of a plant or tree","dt":"Bir bitkinin veya ağacın yaprakları","e1":"Lush green foliage.","e1t":"Gür yeşil bitki örtüsü (yapraklar).","e2":"The autumn foliage is beautiful.","e2t":"Sonbahar yaprakları (yeşilliği) güzeldir."},{"w":"formidable","tr":"korkutucu / dişli / azametli","te":"Adjective","tt":"Sıfat","de":"Causing fear or respect by being very powerful","dt":"Çok güçlü olduğu için korku veya saygı uyandıran","e1":"He is a formidable opponent.","e1t":"O dişli (korkutucu) bir rakiptir.","e2":"A formidable task.","e2t":"Göz korkutucu bir görev."},{"w":"formulaic","tr":"kalıplaşmış / formüle dayalı","te":"Adjective","tt":"Sıfat","de":"Made of fixed patterns or formulas","dt":"Sabit kalıplardan veya formüllerden oluşan","e1":"A formulaic plot.","e1t":"Kalıplaşmış (sıradan) bir olay örgüsü.","e2":"Formulaic language.","e2t":"Kalıp ifadeler."},{"w":"forthcoming","tr":"yaklaşan / gelecek / yardımsever (bilgi verme konusunda)","te":"Adjective","tt":"Sıfat","de":"Happening soon; or willing to give information","dt":"Yakında olacak; veya bilgi vermeye istekli","e1":"The forthcoming elections.","e1t":"Yaklaşan seçimler.","e2":"He wasn't very forthcoming about his plans.","e2t":"Planları hakkında pek açık (yardımsever) davranmadı."},{"w":"fraudulent","tr":"sahtekâr / dolandırıcı / hileli","te":"Adjective","tt":"Sıfat","de":"Intended to deceive; dishonest","dt":"Aldatmaya yönelik; dürüst olmayan","e1":"Fraudulent insurance claims.","e1t":"Hileli sigorta talepleri.","e2":"A fraudulent scheme.","e2t":"Dolandırıcılık planı."},{"w":"freak","tr":"tuhaf kişi / ucube / alışılmadık olay","te":"Noun/Adjective/Verb","tt":"A person or event that is very unusual","de":"Çok alışılmadık kişi veya olay","dt":"A control freak.","e1":"Kontrol delisi (tuhafı).","e1t":"A freak accident.","e2":"Alışılmadık (garip) bir kaza.","e2t":""},{"w":"freelance","tr":"serbest çalışan","te":"Adjective/Adverb/Noun/Verb","tt":"Working for different companies, not just one","de":"Sadece bir değil, farklı şirketler için çalışma","dt":"He is a freelance journalist.","e1":"O serbest çalışan bir gazetecidir.","e1t":"To work freelance.","e2":"Freelance (serbest) çalışmak.","e2t":""},{"w":"frenzy","tr":"çılgınlık / cinnet / coşku","te":"Noun","tt":"İsim","de":"A state of uncontrolled excitement or wild behavior","dt":"Kontrolsüz heyecan veya çılgın davranış durumu","e1":"The crowd was in a frenzy.","e1t":"Kalabalık çılgınlık (cinnet) halindeydi.","e2":"A shopping frenzy.","e2t":"Alışveriş çılgınlığı."},{"w":"fringe","tr":"kenar / saçak / marjinal","te":"Noun/Adjective/Verb","tt":"The outer edge of something; or not part of the main group","de":"Bir şeyin dış kenarı; veya ana grubun parçası olmayan","dt":"On the fringe of the city.","e1":"Şehrin kenarında (çeperinde).","e1t":"Fringe benefits.","e2":"Yan haklar (ek avantajlar).","e2t":""},{"w":"frivolous","tr":"önemsiz / ciddiyetsiz / boş","te":"Adjective","tt":"Sıfat","de":"Not serious or important; silly","dt":"Ciddi veya önemli olmayan; aptalca","e1":"A frivolous lawsuit.","e1t":"Ciddiyetsiz (boş) bir dava.","e2":"Frivolous behavior.","e2t":"Ciddiyetsiz davranış."},{"w":"frosty","tr":"ayazlı / buz gibi / soğuk (tavır)","te":"Adjective","tt":"Sıfat","de":"Very cold, covered with frost; or unfriendly","dt":"Çok soğuk, kırağı ile kaplı; veya soğuk (tavır)","e1":"A frosty morning.","e1t":"Ayazlı bir sabah.","e2":"He gave me a frosty look.","e2t":"Bana buz gibi (soğuk) bir bakış attı."},{"w":"fugitive","tr":"kaçak kişi / firari","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is running away, especially from the police","dt":"Kaçan kişi, özellikle polisten kaçan","e1":"The fugitive was caught at the border.","e1t":"Firari sınırda yakalandı.","e2":"A fugitive from justice.","e2t":"Adaletten kaçan kişi."},{"w":"fulfillment / fulfilment","tr":"yerine getirme / tatmin / başarma","te":"Noun","tt":"İsim","de":"The feeling of being satisfied; or completing a task","dt":"Tatmin hissi; veya bir görevi tamamlama","e1":"Personal fulfillment.","e1t":"Kişisel tatmin.","e2":"The fulfillment of a promise.","e2t":"Bir sözün yerine getirilmesi."},{"w":"fungus","tr":"mantar (küf, maya vb.)","te":"Noun","tt":"İsim","de":"A plant","dt":"like organism that has no leaves or flowers","e1":"Yaprağı veya çiçeği olmayan bitki benzeri organizma","e1t":"Mushrooms are a type of fungus.","e2":"Mantarlar bir tür fungustur.","e2t":"The tree was covered with fungus."},{"w":"fuse","tr":"eritmek / birleşmek / fitil / sigorta","te":"Noun/Verb","tt":"İsim/Fiil","de":"To join together; or a part that stops electricity","dt":"Birleşmek; veya elektriği durduran parça (sigorta)","e1":"The two companies fused into one.","e1t":"İki şirket birleşip tek bir yapı oldu.","e2":"A blown fuse.","e2t":"Atmış bir sigorta."},{"w":"galaxy","tr":"galaksi / gökada","te":"Noun","tt":"İsim","de":"A large system of stars in outer space","dt":"Uzaydaki devasa yıldız sistemi","e1":"The Milky Way galaxy.","e1t":"Samanyolu galaksisi.","e2":"A galaxy of stars.","e2t":"Yıldız kümesi (galaksisi)."},{"w":"gale","tr":"kuvvetli rüzgâr / fırtına","te":"Noun","tt":"İsim","de":"A very strong wind","dt":"Çok güçlü rüzgâr","e1":"The ship was lost in a gale.","e1t":"Gemi bir fırtınada (kuvvetli rüzgârda) kayboldu.","e2":"Gales of laughter.","e2t":"Kahkaha tufanı (fırtınası)."},{"w":"gallop","tr":"dörtnala koşmak / dörtnala","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a horse) to run very fast","dt":"(At için) çok hızlı koşmak","e1":"The horse galloped across the field.","e1t":"At tarlada dörtnala koştu.","e2":"At a full gallop.","e2t":"Tam dörtnala."},{"w":"gangway","tr":"geçit / yürüme yolu / (gemide) iskele","te":"Noun","tt":"İsim","de":"A passage or a bridge to enter a ship","dt":"Geçit veya gemiye giriş iskelesi","e1":"Please clear the gangway.","e1t":"Lütfen geçidi boşaltın.","e2":"We walked down the gangway.","e2t":"İskeleden (yürüme yolundan) aşağı yürüdük."},{"w":"gape","tr":"ağzı açık bakmak / şaşkınlıkla bakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look at something with your mouth open in surprise","dt":"Şaşkınlıktan ağzı açık bir şekilde bakmak","e1":"He gaped at the giant statue.","e1t":"Dev heykele ağzı açık bakakaldı.","e2":"A gaping hole.","e2t":"Kocaman (açık) bir delik."},{"w":"garner","tr":"toplamak / biriktirmek / kazanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To collect or get something, especially after effort","dt":"Özellikle çabadan sonra bir şeyi toplamak veya elde etmek","e1":"The movie garnered many awards.","e1t":"Film birçok ödül kazandı (topladı).","e2":"To garner support.","e2t":"Destek toplamak."},{"w":"garnish","tr":"süslemek / garnitür / (maaşa) el koymak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To decorate food; or to take money from a salary","dt":"Yemeği süslemek; veya maaştan para kesmek","e1":"Garnish the dish with parsley.","e1t":"Yemeği maydanozla süsleyin.","e2":"Lemon garnish.","e2t":"Limon garnitürü."},{"w":"genealogy","tr":"soybilim / şecere","te":"Noun","tt":"İsim","de":"The study of family history","dt":"Aile tarihinin incelenmesi","e1":"He is interested in his family's genealogy.","e1t":"Ailesinin şeceresiyle (soybilimiyle) ilgileniyor.","e2":"A genealogy tree.","e2t":"Soy ağacı."},{"w":"generic","tr":"genel / markasız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a whole group; or not having a brand name","dt":"Tüm bir grupla ilgili; veya marka adı olmayan","e1":"Generic drugs are cheaper.","e1t":"Markasız (muadil) ilaçlar daha ucuzdur.","e2":"A generic term for software.","e2t":"Yazılım için genel bir terim."},{"w":"genetic","tr":"genetik / kalıtsal","te":"Adjective","tt":"Sıfat","de":"Relating to genes or heredity","dt":"Genler veya kalıtım ile ilgili","e1":"Genetic engineering.","e1t":"Genetik mühendisliği.","e2":"A genetic disorder.","e2t":"Genetik (kalıtsal) bir bozukluk."},{"w":"genius","tr":"dahi / deha / yetenek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person of very great intelligence or skill","dt":"Çok zeki veya yetenekli kişi","e1":"Einstein was a mathematical genius.","e1t":"Einstein matematiksel bir dahiydi.","e2":"A stroke of genius.","e2t":"Deha eseri (dahice bir fikir)."},{"w":"genre","tr":"tür (sanat, edebiyat vb.)","te":"Noun","tt":"İsim","de":"A particular style or type of art, music, or writing","dt":"Sanat, müzik veya yazının belirli bir tarzı veya türü","e1":"My favorite film genre is science fiction.","e1t":"En sevdiğim film türü bilim kurgudur.","e2":"Literary genre.","e2t":"Edebi tür."},{"w":"genuine","tr":"gerçek / samimi / özgün","te":"Adjective","tt":"Sıfat","de":"Real and exactly what it appears to be; sincere","dt":"Gerçek ve göründüğü gibi olan; samimi","e1":"Is this a genuine diamond?","e1t":"Bu gerçek bir elmas mı?","e2":"A genuine apology.","e2t":"Samimi bir özür."},{"w":"geology","tr":"yer bilimi / jeoloji","te":"Noun","tt":"İsim","de":"The study of the Earth's structure and rocks","dt":"Dünya'nın yapısının ve kayaların incelenmesi","e1":"He has a degree in geology.","e1t":"Jeoloji (yer bilimi) diploması var.","e2":"The geology of the region.","e2t":"Bölgenin jeolojisi."},{"w":"germinate","tr":"filizlenmek / yeşermek / (fikir) doğmak","te":"Verb","tt":"Fiil","de":"(Of a seed) to start to grow","dt":"(Tohum için) büyümeye başlamak","e1":"The seeds will germinate in warm weather.","e1t":"Tohumlar sıcak havada filizlenecektir.","e2":"An idea began to germinate in his mind.","e2t":"Zihninde bir fikir doğmaya (yeşermeye) başladı."},{"w":"gigantic","tr":"devasa / dev gibi / muazzam","te":"Adjective","tt":"Sıfat","de":"Extremely large","dt":"Son derece büyük","e1":"A gigantic wave hit the coast.","e1t":"Sahile devasa bir dalga vurdu.","e2":"The project was a gigantic task.","e2t":"Proje muazzam bir görevdi."},{"w":"gist","tr":"ana fikir / öz / asıl mesele","te":"Noun","tt":"İsim","de":"The main point or general meaning of something","dt":"Bir şeyin ana noktası veya genel anlamı","e1":"I didn't catch every word, but I got the gist of the story.","e1t":"Her kelimeyi yakalayamadım ama hikayenin ana fikrini anladım.","e2":"The gist of his argument.","e2t":"İddiasının özü."},{"w":"gleam","tr":"parlamak / parıltı / (gözde) ışık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shine brightly, especially with reflected light","dt":"Özellikle yansıyan ışıkla parlak bir şekilde ışıldamak","e1":"His eyes gleamed with excitement.","e1t":"Gözleri heyecanla parladı.","e2":"The gleam of a lighthouse.","e2t":"Deniz fenerinin parıltısı."},{"w":"glide","tr":"süzülmek / kaymak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move smoothly and easily","dt":"Sorunsuz ve kolayca hareket etmek","e1":"The eagle glided through the air.","e1t":"Kartal havada süzüldü.","e2":"To glide on ice.","e2t":"Buzda kaymak."},{"w":"glimmer","tr":"hafif ışık / pırıltı / belirti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A faint or unsteady light; or a slight sign","dt":"Hafif veya titrek ışık; veya hafif bir işaret","e1":"A glimmer of light in the distance.","e1t":"Uzakta hafif bir ışık pırıltısı.","e2":"A glimmer of hope.","e2t":"Bir umut ışığı (belirtisi)."},{"w":"glimpse","tr":"kısa bakış / anlık görmek / gözüne ilişmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"To see something for a very short time","dt":"Bir şeyi çok kısa bir süreliğine görmek","e1":"I caught a glimpse of the celebrity.","e1t":"Ünlüyü anlık (şöyle bir) gördüm.","e2":"To glimpse the future.","e2t":"Geleceğe kısa bir bakış atmak."},{"w":"glitter","tr":"parıltı / ışıldamak / sim","te":"Noun/Verb","tt":"İsim/Fiil","de":"To produce a lot of small, bright flashes of light","dt":"Çok sayıda küçük, parlak ışık patlaması üretmek","e1":"Her diamond ring glittered in the sun.","e1t":"Elmas yüzüğü güneşte ışıldadı.","e2":"All that glitters is not gold.","e2t":"Parlayan her şey altın değildir."},{"w":"globalize / globalise","tr":"küreselleştirmek","te":"Verb","tt":"Fiil","de":"To make something operate worldwide","dt":"Bir şeyi dünya çapında işler hale getirmek","e1":"The internet has globalized the economy.","e1t":"İnternet ekonomiyi küreselleştirdi.","e2":"Globalizing markets.","e2t":"Küreselleşen pazarlar."},{"w":"gloom","tr":"karanlık / hüzün / karamsarlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"Near darkness or a feeling of sadness","dt":"Yarı karanlık veya üzüntü hissi","e1":"The room was in gloom.","e1t":"Oda karanlık içindeydi.","e2":"A feeling of gloom and doom.","e2t":"Karamsarlık ve yıkım hissi."},{"w":"glorious","tr":"görkemli / şanlı / muhteşem","te":"Adjective","tt":"Sıfat","de":"Deserving great admiration or praise; or very beautiful","dt":"Büyük hayranlık veya övgü hak eden; veya çok güzel","e1":"A glorious victory.","e1t":"Şanlı bir zafer.","e2":"The sunset was glorious.","e2t":"Gün batımı muhteşemdi."},{"w":"glow","tr":"parıldamak / kor / sıcaklık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce a steady, soft light","dt":"Sabit, yumuşak bir ışık üretmek","e1":"The embers glowed in the fireplace.","e1t":"Şöminede közler parlıyordu.","e2":"Her face glowed with happiness.","e2t":"Yüzü mutluluktan parlıyordu (ışıldıyordu)."},{"w":"gnaw","tr":"kemirmek / aşındırmak / (vicdan) sızlatmak","te":"Verb","tt":"Fiil","de":"To bite or chew something repeatedly","dt":"Bir şeyi tekrar tekrar ısırmak veya çiğnemek","e1":"The rat gnawed a hole in the wall.","e1t":"Fare duvarda bir delik kemirdi.","e2":"Guilt began to gnaw at him.","e2t":"Suçluluk duygusu onu kemirmeye (rahatsız etmeye) başladı."},{"w":"gorgeous","tr":"muhteşem / harika / göz alıcı","te":"Adjective","tt":"Sıfat","de":"Very beautiful or pleasant","dt":"Çok güzel veya hoş","e1":"You look gorgeous in that dress!","e1t":"O elbisenin içinde muhteşem görünüyorsun!","e2":"Gorgeous weather.","e2t":"Harika hava."},{"w":"governance","tr":"yönetişim / yönetim biçimi","te":"Noun","tt":"İsim","de":"The way that a country or organization is controlled","dt":"Bir ülkenin veya kuruluşun kontrol edilme biçimi","e1":"Corporate governance.","e1t":"Kurumsal yönetişim.","e2":"Good governance is essential for development.","e2t":"İyi yönetişim kalkınma için esastır."},{"w":"gracious","tr":"zarif / kibar / merhametli","te":"Adjective/Interjection","tt":"Kind, polite, and generous","de":"Nazik, kibar ve cömert","dt":"A gracious host.","e1":"Nazik (zarif) bir ev sahibi.","e1t":"Good gracious!","e2":"Aman Tanrım! (Hayret ifadesi).","e2t":""},{"w":"gradient","tr":"gradyan / eğim / meyil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A measure of how steep a slope is","dt":"Bir yamacın ne kadar dik olduğunun ölçüsü","e1":"A steep gradient.","e1t":"Dik bir eğim.","e2":"Temperature gradient.","e2t":"Sıcaklık gradyanı (değişimi)."},{"w":"grainy","tr":"grenli / pürüzlü / kumlu","te":"Adjective","tt":"Sıfat","de":"Having a rough surface or looking like it is made of grains","dt":"Pürüzlü bir yüzeye sahip veya tanecikli görünen","e1":"The photo was old and grainy.","e1t":"Fotoğraf eski ve grenliydi (kumlanmıştı).","e2":"Grainy bread.","e2t":"Tahıllı (pürüzlü) ekmek."},{"w":"grandeur","tr":"ihtişam / görkem / azamet","te":"Noun","tt":"İsim","de":"The quality of being very large and impressive","dt":"Çok büyük ve etkileyici olma niteliği","e1":"The grandeur of the Ottoman palaces.","e1t":"Osmanlı saraylarının ihtişamı.","e2":"Delusions of grandeur.","e2t":"Büyüklük hezeyanları."},{"w":"granite","tr":"granit","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very hard, grey rock used in building","dt":"İnşaatta kullanılan çok sert, gri kaya","e1":"The counter is made of solid granite.","e1t":"Tezgah masif granitten yapılmıştır.","e2":"Granite walls.","e2t":"Granit duvarlar."},{"w":"graphic","tr":"grafiksel / canlı / betimleyici","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to visual art; or giving a clear, vivid picture","dt":"Görsel sanatla ilgili; veya net, canlı bir resim çizen","e1":"A graphic novel.","e1t":"Grafik roman.","e2":"He gave a graphic description of the accident.","e2t":"Kazanın çok canlı (ayrıntılı) bir betimlemesini yaptı."},{"w":"gratify","tr":"memnun etmek / tatmin etmek","te":"Verb","tt":"Fiil","de":"To please someone or to satisfy a wish","dt":"Birini memnun etmek veya bir arzuyu tatmin etmek","e1":"I was gratified to see my students succeed.","e1t":"Öğrencilerimin başarılı olduğunu görmek beni memnun etti.","e2":"To gratify a desire.","e2t":"Bir arzuyu tatmin etmek."},{"w":"gravitational","tr":"yerçekimsel","te":"Adjective","tt":"Sıfat","de":"Relating to the force of gravity","dt":"Yerçekimi kuvveti ile ilgili","e1":"Gravitational pull.","e1t":"Yerçekimi kuvveti (çekimi).","e2":"Gravitational waves.","e2t":"Kütleçekim dalgaları."},{"w":"grievance","tr":"şikayet / yakınma / sızlanma","te":"Noun","tt":"İsim","de":"A complaint or a strong feeling that you have been treated unfairly","dt":"Şikayet veya adaletsizliğe uğrama hissi","e1":"To file a formal grievance.","e1t":"Resmi bir şikayette bulunmak.","e2":"He has a list of grievances against the company.","e2t":"Şirkete karşı bir şikayet listesi var."},{"w":"grim","tr":"kasvetli / sert / korkunç","te":"Adjective","tt":"Sıfat","de":"Very serious, gloomy, or without hope","dt":"Çok ciddi, kasvetli veya umutsuz","e1":"The future looks grim.","e1t":"Gelecek kasvetli (umutsuz) görünüyor.","e2":"A grim expression.","e2t":"Sert (asık) bir yüz ifadesi."},{"w":"groan","tr":"inlemek / gıcırdamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a deep, long sound of pain or unhappiness","dt":"Acı veya mutsuzlukla derin, uzun bir ses çıkarmak","e1":"He groaned in pain.","e1t":"Acıyla inledi.","e2":"The floorboards groaned.","e2t":"Yer tahtaları gıcırdadı."},{"w":"groundwork","tr":"zemin hazırlığı / temel / hazırlık çalışması","te":"Noun","tt":"İsim","de":"Preparatory work for something","dt":"Bir şey için yapılan ön hazırlık çalışması","e1":"The meeting laid the groundwork for future talks.","e1t":"Toplantı, gelecekteki görüşmeler için zemin hazırladı.","e2":"To do the groundwork.","e2t":"Temel hazırlıkları yapmak."},{"w":"guardian","tr":"vasi / koruyucu / muhafız","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has the legal right to take care of someone","dt":"Birine bakma yasal hakkına sahip kişi","e1":"Legal guardian.","e1t":"Yasal vasi.","e2":"Guardian angel.","e2t":"Koruyucu melek."},{"w":"gush","tr":"fışkırmak / coşkuyla anlatmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To flow out quickly in large amounts","dt":"Büyük miktarlarda hızla dışarı akmak","e1":"Water gushed from the broken pipe.","e1t":"Kırık borudan su fışkırdı.","e2":"She gushed about her new job.","e2t":"Yeni işi hakkında coşkuyla (ballandıra ballandıra) anlattı."},{"w":"hallmark","tr":"ayırt edici özellik / kalite damgası","te":"Noun/Verb","tt":"İsim/Fiil","de":"A typical characteristic or feature of something","dt":"Bir şeyin tipik bir karakteristiği veya özelliği","e1":"Attention to detail is the hallmark of his work.","e1t":"Detaylara verilen önem onun işinin ayırt edici özelliğidir.","e2":"Hallmark of excellence.","e2t":"Mükemmellik damgası."},{"w":"handwriting","tr":"el yazısı","te":"Noun","tt":"İsim","de":"The particular way in which someone writes","dt":"Birinin kendine has yazma biçimi","e1":"His handwriting is illegible.","e1t":"Onun el yazısı okunaksız.","e2":"Beautiful handwriting.","e2t":"Güzel el yazısı."},{"w":"harden","tr":"sertleşmek / katılaşmak","te":"Verb","tt":"Fiil","de":"To become or make something hard or firm","dt":"Bir şeyi sert veya katı hale getirmek/gelmek","e1":"The cement takes hours to harden.","e1t":"Çimentonun sertleşmesi saatler sürer.","e2":"Years of struggle had hardened him.","e2t":"Yıllar süren mücadele onu sertleştirmişti."},{"w":"headline","tr":"manşet / ana başlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"The title of a newspaper story","dt":"Gazete haberinin başlığı","e1":"Front","e1t":"page headline.","e2":"Ön sayfa manşeti.","e2t":"To make headlines (to become famous)."},{"w":"heartfelt","tr":"samimi / içten / yürekten","te":"Adjective","tt":"Sıfat","de":"Strongly and sincerely felt","dt":"Güçlü ve samimi bir şekilde hissedilen","e1":"Heartfelt thanks.","e1t":"İçten teşekkürler.","e2":"A heartfelt apology.","e2t":"Yürekten (samimi) bir özür."},{"w":"hearty","tr":"içten / samimi / doyurucu (yemek)","te":"Adjective","tt":"Sıfat","de":"Enthusiastic and friendly; or large (of a meal)","dt":"Coşkulu ve dostça; veya büyük/bol (yemek için)","e1":"A hearty welcome.","e1t":"Samimi (sıcak) bir karşılama.","e2":"A hearty breakfast.","e2t":"Doyurucu (sağlam) bir kahvaltı."},{"w":"heatwave","tr":"sıcak hava dalgası","te":"Noun","tt":"İsim","de":"A period of unusually hot weather","dt":"Olağandışı sıcak hava dönemi","e1":"The heatwave lasted for two weeks.","e1t":"Sıcak hava dalgası iki hafta sürdü.","e2":"To survive a heatwave.","e2t":"Bir sıcak hava dalgasını atlatmak."},{"w":"heed","tr":"dikkat etmek / kulak asmak / uyarıyı dinlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pay attention to advice or a warning","dt":"Tavsiyeye veya uyarıya dikkat etmek","e1":"Heed my words.","e1t":"Sözlerime kulak ver (dikkat et).","e2":"He failed to heed the warning.","e2t":"Uyarıyı dinlemeyi başaramadı (dikkate almadı)."},{"w":"heighten","tr":"artırmak / yükseltmek / şiddetlendirmek","te":"Verb","tt":"Fiil","de":"To increase or make something stronger","dt":"Bir şeyi artırmak veya daha güçlü hale getirmek","e1":"The tension began to heighten.","e1t":"Gerginlik artmaya başladı.","e2":"To heighten awareness.","e2t":"Farkındalığı yükseltmek (artırmak)."},{"w":"heir","tr":"mirasçı / varis","te":"Noun","tt":"İsim","de":"A person who will receive money or a title when someone dies","dt":"Biri öldüğünde parasını veya unvanını alacak kişi","e1":"The heir to the throne.","e1t":"Tahtın varisi.","e2":"Sole heir.","e2t":"Tek mirasçı."},{"w":"helium","tr":"helyum","te":"Noun","tt":"İsim","de":"A very light gas that does not burn","dt":"Yanmayan, çok hafif bir gaz","e1":"Helium balloons.","e1t":"Helyum balonları.","e2":"Helium is used in deep","e2t":"sea diving."},{"w":"helpdesk","tr":"destek masası / yardım masası","te":"Noun","tt":"İsim","de":"A service that provides information and support to users","dt":"Kullanıcılara bilgi ve destek sağlayan servis","e1":"Call the helpdesk for technical support.","e1t":"Teknik destek için yardım masasını arayın.","e2":"Helpdesk operator.","e2t":"Destek masası operatörü."},{"w":"hemisphere","tr":"yarımküre","te":"Noun","tt":"İsim","de":"One half of the Earth or a sphere","dt":"Dünya'nın veya bir kürenin yarısı","e1":"Northern Hemisphere.","e1t":"Kuzey Yarımküre.","e2":"The left hemisphere of the brain.","e2t":"Beynin sol yarımküresi."},{"w":"hesitant","tr":"tereddütlü / kararsız","te":"Adjective","tt":"Sıfat","de":"Uncertain about what to do or say","dt":"Ne yapacağı veya söyleyeceği konusunda emin olmayan","e1":"He was hesitant to sign the contract.","e1t":"Sözleşmeyi imzalama konusunda tereddütlüydü.","e2":"A hesitant smile.","e2t":"Kararsız bir gülümseme."},{"w":"hierarchy","tr":"hiyerarşi / aşama sırası","te":"Noun","tt":"İsim","de":"A system in which members are ranked according to status","dt":"Üyelerin statüye göre sıralandığı sistem","e1":"Social hierarchy.","e1t":"Sosyal hiyerarşi.","e2":"The corporate hierarchy.","e2t":"Şirket hiyerarşisi."},{"w":"hilarious","tr":"çok komik / gülünç","te":"Adjective","tt":"Sıfat","de":"Extremely funny","dt":"Son derece komik","e1":"A hilarious joke.","e1t":"Çok komik bir şaka.","e2":"The movie was hilarious.","e2t":"Film kahkaha doluydu (çok komikti)."},{"w":"hindrance","tr":"engel / ayak bağı","te":"Noun","tt":"İsim","de":"Something that makes it difficult for you to do something","dt":"Bir şeyi yapmanızı zorlaştıran şey","e1":"A hindrance to progress.","e1t":"İlerlemenin önünde bir engel.","e2":"Without any hindrance.","e2t":"Hiçbir engel olmaksızın."},{"w":"hinge","tr":"menteşe /","te":"e bağlı olmak","tt":"Noun/Verb","de":"İsim/Fiil","dt":"A piece of metal that joins a door to a wall","e1":"Kapıyı duvara bağlayan metal parça","e1t":"The door is off its hinges.","e2":"Kapı menteşelerinden çıkmış.","e2t":"The success of the project hinges on your help."},{"w":"hip","tr":"kalça / havalı / güncel","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The area below the waist on each side of the body","dt":"Vücudun her iki yanında belin altındaki bölge","e1":"He put his hands on his hips.","e1t":"Ellerini kalçasına koydu.","e2":"A hip new restaurant.","e2t":"Havalı (popüler) yeni bir restoran."},{"w":"hitch","tr":"aksilik / pürüz / kanca / otostop çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A minor problem or delay; or to pull up","dt":"Küçük bir sorun veya gecikme; veya yukarı çekmek","e1":"The wedding went off without a hitch.","e1t":"Düğün hiçbir aksilik çıkmadan gerçekleşti.","e2":"To hitch a ride (hitchhike).","e2t":"Otostop çekmek."},{"w":"homage","tr":"saygı / bağlılık / tazim","te":"Noun","tt":"İsim","de":"Deep respect or honor shown publicly","dt":"Kamuoyuna gösterilen derin saygı veya onur","e1":"To pay homage to the fallen soldiers.","e1t":"Şehit düşen askerlere saygısını sunmak (tazimde bulunmak).","e2":"The film is a homage to old Hollywood.","e2t":"Film, eski Hollywood'a bir saygı duruşudur."},{"w":"homeland","tr":"anavatan / vatan","te":"Noun","tt":"İsim","de":"The country where you were born","dt":"Doğduğunuz ülke","e1":"He returned to his homeland after twenty years.","e1t":"Yirmi yıl sonra anavatanına döndü.","e2":"To protect the homeland.","e2t":"Vatanı korumak."},{"w":"hormone","tr":"hormon","te":"Noun","tt":"İsim","de":"A chemical substance produced in the body that controls the way cells work","dt":"Vücutta hücrelerin çalışma şeklini kontrol eden kimyasal madde","e1":"Growth hormone.","e1t":"Büyüme hormonu.","e2":"Adrenaline is a hormone produced in response to stress.","e2t":"Adrenalin, strese tepki olarak üretilen bir hormondur."},{"w":"hostility","tr":"düşmanlık / husumet","te":"Noun","tt":"İsim","de":"Unfriendly or aggressive behavior","dt":"Dostça olmayan veya saldırgan davranış","e1":"There was open hostility between the two groups.","e1t":"İki grup arasında açık bir düşmanlık vardı.","e2":"To end hostilities.","e2t":"Çatışmalara (düşmanlıklara) son vermek."},{"w":"humanitarian","tr":"insancıl / yardımsever / insani","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Involved in improving people's lives and reducing suffering","dt":"İnsanların hayatını iyileştirmek ve acıları azaltmakla ilgili","e1":"Humanitarian aid.","e1t":"İnsani yardım.","e2":"A humanitarian crisis.","e2t":"İnsani kriz."},{"w":"humid","tr":"nemli / rutubetli","te":"Adjective","tt":"Sıfat","de":"(Of air or weather) containing a lot of water","dt":"(Hava veya hava durumu için) çok su (nem) içeren","e1":"Tropical climates are very hot and humid.","e1t":"Tropikal iklimler çok sıcak ve nemlidir.","e2":"A humid afternoon.","e2t":"Nemli bir öğleden sonra."},{"w":"hunch","tr":"sezgi / his / kambur","te":"Noun/Verb","tt":"İsim/Fiil","de":"a feeling that something is true even though you do not have evidence","dt":"Kanıtınız olmasa bile bir şeyin doğru olduğuna dair his","e1":"I had a hunch that you would be here.","e1t":"Burada olacağına dair bir hissim (sezgim) vardı.","e2":"To sit with a hunch.","e2t":"Kambur oturmak."},{"w":"hurdle","tr":"engel (yarış) / güçlük / aşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A frame that people jump over in a race; or a problem","dt":"İnsanların bir yarışta üzerinden atladığı çerçeve; veya sorun","e1":"To clear a hurdle.","e1t":"Bir engeli aşmak.","e2":"The first hurdle to overcome is the language barrier.","e2t":"Aşılması gereken ilk engel dil bariyeridir."},{"w":"hybrid","tr":"hibrit / melez / karma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something that is a mixture of two very different things","dt":"İki çok farklı şeyin karışımı olan şey","e1":"A hybrid car (electric and petrol).","e1t":"Hibrit araba (elektrikli ve benzinli).","e2":"A hybrid rose.","e2t":"Melez bir gül."},{"w":"hydroelectric","tr":"hidroelektrik","te":"Adjective","tt":"Sıfat","de":"Producing electricity by the force of moving water","dt":"Hareket eden suyun gücüyle elektrik üretme","e1":"A hydroelectric power station.","e1t":"Hidroelektrik santrali.","e2":"Hydroelectric dam.","e2t":"Hidroelektrik barajı."},{"w":"hysterical","tr":"çılgınca / histerik / kontrolsüz","te":"Adjective","tt":"Sıfat","de":"Unable to control your feelings or behavior because of fear or excitement","dt":"Korku veya heyecan nedeniyle duygularını kontrol edememe","e1":"Hysterical laughter.","e1t":"Sinirsel (kontrolsüz) kahkaha.","e2":"He became hysterical when he heard the news.","e2t":"Haberi duyduğunda kendini kaybetti (histerikleşti)."},{"w":"iconic","tr":"simgesel / ikonik","te":"Adjective","tt":"Sıfat","de":"Very famous or popular and considered to represent a particular idea","dt":"Çok ünlü ve belirli bir fikri temsil ettiği düşünülen","e1":"The Eiffel Tower is an iconic landmark.","e1t":"Eyfel Kulesi ikonik (simgesel) bir yapıdır.","e2":"An iconic image of the 20th century.","e2t":"20. yüzyılın simgesel bir görüntüsü."},{"w":"ideology","tr":"ideoloji / fikir sistemi","te":"Noun","tt":"İsim","de":"A set of beliefs or principles, especially political ones","dt":"Özellikle siyasi inançlar veya ilkeler bütünü","e1":"Political ideology.","e1t":"Siyasi ideoloji.","e2":"Dominant ideology.","e2t":"Baskın ideoloji."},{"w":"ignite","tr":"ateşlemek / tutuşturmak / parlamak","te":"Verb","tt":"Fiil","de":"To start to burn or to make something start to burn","dt":"Yanmaya başlamak veya bir şeyi yakmak","e1":"The spark ignited the fuel.","e1t":"Kıvılcım yakıtı ateşledi.","e2":"To ignite a passion for learning.","e2t":"Öğrenme tutkusunu ateşlemek."},{"w":"ignorance","tr":"cehalet / bilgisizlik","te":"Noun","tt":"İsim","de":"Lack of knowledge or information about something","dt":"Bir şey hakkında bilgi veya veri eksikliği","e1":"Ignorance of the law is no excuse.","e1t":"Yasayı bilmemek (cehalet) bir mazeret değildir.","e2":"Total ignorance.","e2t":"Tam bir bilgisizlik."},{"w":"illuminate","tr":"aydınlatmak / ışıklandırmak / açıklığa kavuşturmak","te":"Verb","tt":"Fiil","de":"To light up or to make something clear","dt":"Işıklandırmak veya bir şeyi netleştirmek","e1":"The streets were illuminated by streetlights.","e1t":"Sokaklar sokak lambalarıyla aydınlatıldı.","e2":"To illuminate a complex issue.","e2t":"Karmaşık bir konuyu aydınlatmak (açıklamak)."},{"w":"illusion","tr":"yanılsama / illüzyon / hayal","te":"Noun","tt":"İsim","de":"An idea or belief that is not true","dt":"Doğru olmayan bir fikir veya inanç","e1":"Optical illusion.","e1t":"Optik yanılsama (göz yanılması).","e2":"Under the illusion that...","e2t":"... olduğu hayaliyle (yanılsamasıyla)."},{"w":"imminent","tr":"eli kulağında / yakın / olması beklenen","te":"Adjective","tt":"Sıfat","de":"Coming or happening very soon","dt":"Çok yakında gelecek veya gerçekleşecek olan","e1":"A decision is imminent.","e1t":"Karar verilmek üzere (eli kulağında).","e2":"In imminent danger.","e2t":"Yakın tehlike altında."},{"w":"immune","tr":"bağışık / etkilenmez / muaf","te":"Adjective","tt":"Sıfat","de":"Protected against a particular disease; or not affected","dt":"Belirli bir hastalığa karşı korunan; veya etkilenmeyen","e1":"Immune system.","e1t":"Bağışıklık sistemi.","e2":"He is immune to criticism.","e2t":"Eleştiriden etkilenmez (bağışıklığı var)."},{"w":"impartial","tr":"tarafsız / nesnel","te":"Adjective","tt":"Sıfat","de":"Not supporting one person or group more than another","dt":"Bir kişi veya grubu diğerinden daha fazla desteklemeyen","e1":"An impartial judge.","e1t":"Tarafsız bir yargıç.","e2":"To give impartial advice.","e2t":"Tarafsız tavsiye vermek."},{"w":"impatience","tr":"sabırsızlık","te":"Noun","tt":"İsim","de":"The feeling of being annoyed because something is slow","dt":"Bir şeyin yavaş olması nedeniyle duyulan rahatsızlık hissi","e1":"He showed signs of impatience.","e1t":"Sabırsızlık belirtileri gösterdi.","e2":"In her impatience to leave...","e2t":"Gitme sabırsızlığıyla..."},{"w":"imperial","tr":"imparatorlukla ilgili / görkemli","te":"Adjective","tt":"Sıfat","de":"Relating to an empire or an emperor","dt":"Bir imparatorluk veya imparator ile ilgili","e1":"The Imperial Palace.","e1t":"İmparatorluk Sarayı.","e2":"Imperial history.","e2t":"İmparatorluk tarihi."},{"w":"implicit","tr":"üstü kapalı / ima edilen / tam (güven vb.)","te":"Adjective","tt":"Sıfat","de":"Suggested but not stated directly","dt":"Doğrudan söylenmeyen ama ima edilen","e1":"Implicit criticism.","e1t":"Üstü kapalı (dolaylı) eleştiri.","e2":"Implicit trust.","e2t":"Tam (koşulsuz) güven."},{"w":"impoverish","tr":"fakirleştirmek / yoksullaştırmak","te":"Verb","tt":"Fiil","de":"To make someone very poor","dt":"Birini çok fakir hale getirmek","e1":"The war impoverished the nation.","e1t":"Savaş ulusu fakirleştirdi.","e2":"Impoverished soil.","e2t":"Verimsizleşmiş (fakirleşmiş) toprak."},{"w":"impression","tr":"izlenim / baskı / taklit","te":"Noun","tt":"İsim","de":"An idea, feeling, or opinion about someone or something","dt":"Biri veya bir şey hakkındaki fikir veya görüş","e1":"First impressions are important.","e1t":"İlk izlenimler önemlidir.","e2":"To make an impression.","e2t":"İzlenim bırakmak (etkilemek)."},{"w":"imprisonment","tr":"hapis / hapsedilme","te":"Noun","tt":"İsim","de":"The state of being in prison","dt":"Hapiste olma durumu","e1":"Life imprisonment.","e1t":"Müebbet hapis cezası.","e2":"False imprisonment.","e2t":"Haksız yere hapsedilme."},{"w":"inaccessible","tr":"erişilemez / ulaşılmaz","te":"Adjective","tt":"Sıfat","de":"Difficult or impossible to reach","dt":"Ulaşması zor veya imkansız olan","e1":"The village is inaccessible by car.","e1t":"Köye arabayla ulaşılamaz.","e2":"Inaccessible data.","e2t":"Erişilemez veri."},{"w":"inaccuracy","tr":"hatalılık / yanlışlık","te":"Noun","tt":"İsim","de":"A mistake or the state of not being accurate","dt":"Hata veya doğru olmama durumu","e1":"The report is full of inaccuracies.","e1t":"Rapor yanlışlarla (hatalarla) dolu.","e2":"To correct an inaccuracy.","e2t":"Bir yanlışı düzeltmek."},{"w":"incapable","tr":"yeteneksiz / yapamaz / aciz","te":"Adjective","tt":"Sıfat","de":"Unable to do something","dt":"Bir şeyi yapamayan","e1":"He is incapable of telling a lie.","e1t":"Yalan söylemekten acizdir (yapamaz).","e2":"Incapable of working.","e2t":"Çalışamaz durumda."},{"w":"incense","tr":"tütsü / çok kızdırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"a substance that produces a sweet smell when burned; or to make very angry","dt":"Yandığında tatlı bir koku çıkaran madde; veya çok öfkelendirmek","e1":"The smell of burning incense.","e1t":"Yanan tütsü kokusu.","e2":"He was incensed by the decision.","e2t":"Karar karşısında küplere bindi (çok kızdı)."},{"w":"incidence","tr":"vaka / olay sıklığı / görülme oranı","te":"Noun","tt":"İsim","de":"The rate at which something happens","dt":"Bir şeyin gerçekleşme oranı","e1":"A high incidence of heart disease.","e1t":"Kalp hastalığının yüksek görülme oranı.","e2":"The incidence of crime.","e2t":"Suç oranı (vaka sıklığı)."},{"w":"incidentally","tr":"laf arasında / tesadüfen / bu arada","te":"Adverb","tt":"Zarf","de":"Used to add more information; or by chance","dt":"Daha fazla bilgi eklemek için kullanılır; veya şans eseri","e1":"Incidentally, have you seen my keys?","e1t":"Bu arada (laf arasında), anahtarlarımı gördün mü?","e2":"It happened incidentally.","e2t":"Tesadüfen gerçekleşti."},{"w":"inclination","tr":"eğilim / meyil / heves","te":"Noun","tt":"İsim","de":"A feeling that makes you want to do something","dt":"Bir şeyi yapma isteği uyandıran his","e1":"He has an inclination for music.","e1t":"Müziğe karşı bir eğilimi var.","e2":"By natural inclination.","e2t":"Doğal eğilimle."},{"w":"incline","tr":"eğilimi olmak / yokuş / eğmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To think that a particular belief or opinion is likely; or a slope","dt":"Belirli bir inancın olası olduğunu düşünmek; veya eğim","e1":"I incline to the view that...","e1t":"... görüşüne meyilliyim (eğilimliyim).","e2":"A steep incline.","e2t":"Dik bir yokuş."},{"w":"incompetent","tr":"beceriksiz / yetersiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not having the skill or ability to do something well","dt":"Bir şeyi iyi yapacak beceriye veya yeteneğe sahip olmayan","e1":"An incompetent manager.","e1t":"Beceriksiz bir müdür.","e2":"He is professionally incompetent.","e2t":"Mesleki açıdan yetersizdir."},{"w":"inconsistent","tr":"tutarsız / değişken","te":"Adjective","tt":"Sıfat","de":"Not staying the same or not matching","dt":"Aynı kalmayan veya birbirine uymayan","e1":"His results are inconsistent.","e1t":"Sonuçları tutarsız.","e2":"Inconsistent behavior.","e2t":"Değişken (istikrarsız) davranış."},{"w":"inconvenience","tr":"zahmet / rahatsızlık / zorluk","te":"Noun/Verb","tt":"İsim/Fiil","de":"Trouble or problems, especially concerning what you need","dt":"Özellikle ihtiyacınız olan şeyle ilgili sorun veya zorluk","e1":"I'm sorry for the inconvenience.","e1t":"Verdiğim rahatsızlık (zahmet) için özür dilerim.","e2":"The delay inconvenienced many passengers.","e2t":"Gecikme birçok yolcuyu mağdur etti (zorluk çıkardı)."},{"w":"incurable","tr":"iyileşmez / çaresiz (hastalık)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"That cannot be cured","dt":"Tedavi edilemeyen","e1":"An incurable disease.","e1t":"İyileşmez (çaresiz) bir hastalık.","e2":"An incurable romantic.","e2t":"İflah olmaz (çaresiz) bir romantik."},{"w":"indebted","tr":"borçlu / minnettar","te":"Adjective","tt":"Sıfat","de":"Owing money or feeling gratitude","dt":"Para borcu olan veya minnet duyan","e1":"I am deeply indebted to you for your help.","e1t":"Yardımınız için size minnettarım.","e2":"Heavily indebted countries.","e2t":"Gırtlağına kadar borçlu ülkeler."},{"w":"indecent","tr":"edepsiz / ahlaksız / yakışıksız","te":"Adjective","tt":"Sıfat","de":"Morally offensive or not appropriate","dt":"Ahlaki açıdan rahatsız edici veya uygun olmayan","e1":"Indecent behavior.","e1t":"Edepsizce davranış.","e2":"An indecent proposal.","e2t":"Ahlaksız bir teklif."},{"w":"indefinite","tr":"belirsiz / süresiz","te":"Adjective","tt":"Sıfat","de":"Not having a fixed limit or not clear","dt":"Sabit bir sınırı olmayan veya net olmayan","e1":"An indefinite period of time.","e1t":"Belirsiz (veya süresiz) bir zaman dilimi.","e2":"Indefinite article (grammar","e2t":"a/an)."},{"w":"indifference","tr":"kayıtsızlık / umursamazlık","te":"Noun","tt":"İsim","de":"Lack of interest or care","dt":"İlgi veya özen eksikliği","e1":"His total indifference to my problems.","e1t":"Sorunlarıma karşı tam bir kayıtsızlığı.","e2":"A matter of indifference.","e2t":"Önemsiz (fark etmez) bir mesele."},{"w":"indifferent","tr":"kayıtsız / umursamaz / vasat","te":"Adjective","tt":"Sıfat","de":"Not interested or having no opinion; or not good","dt":"İlgisiz veya fikri olmayan; veya iyi olmayan","e1":"He is indifferent to politics.","e1t":"Siyasete karşı kayıtsızdır.","e2":"An indifferent performance.","e2t":"Vasat (orta karar) bir performans."},{"w":"indigenous","tr":"yerli","te":"Adjective","tt":"Sıfat","de":"Naturally existing in a particular place","dt":"Belirli bir yerde doğal olarak var olan","e1":"Indigenous people of Australia.","e1t":"Avustralya'nın yerli halkı.","e2":"Indigenous plants.","e2t":"Yerli bitkiler."},{"w":"indigestible","tr":"hazımsız / sindirilmesi zor","te":"Adjective","tt":"Sıfat","de":"Difficult or impossible to digest","dt":"Sindirimi zor veya imkansız","e1":"Indigestible food.","e1t":"Hazmı zor gıda.","e2":"Indigestible facts (hard to accept).","e2t":"Kabul edilmesi (sindirilmesi) zor gerçekler."},{"w":"indignation","tr":"öfke (haksızlığa karşı) / kızgınlık","te":"Noun","tt":"İsim","de":"Anger about a situation that you think is unfair","dt":"Haksız olduğunu düşündüğünüz bir duruma karşı duyulan öfke","e1":"The decision caused public indignation.","e1t":"Karar halkın öfkesine neden oldu.","e2":"With a feeling of righteous indignation.","e2t":"Haklı bir kızgınlık hissiyle."},{"w":"indirect","tr":"dolaylı","te":"Adjective","tt":"Sıfat","de":"Not direct; happening as a result of something else","dt":"Doğrudan olmayan; başka bir şeyin sonucu olarak gerçekleşen","e1":"An indirect result.","e1t":"Dolaylı bir sonuç.","e2":"Indirect speech (grammar).","e2t":"Dolaylı anlatım."},{"w":"indisputable","tr":"tartışılmaz / kesin","te":"Adjective","tt":"Sıfat","de":"That is true and cannot be disagreed with","dt":"Doğru olan ve aksine itiraz edilemeyen","e1":"It is an indisputable fact.","e1t":"Bu tartışılmaz bir gerçektir.","e2":"Indisputable evidence.","e2t":"Kesin (tartışmasız) kanıt."},{"w":"indistinct","tr":"belirsiz / bulanık / net olmayan","te":"Adjective","tt":"Sıfat","de":"Not clear or not easy to see, hear, or remember","dt":"Net olmayan veya görülmesi, duyulması zor olan","e1":"An indistinct shape in the fog.","e1t":"Siste belirsiz bir şekil.","e2":"Indistinct memories.","e2t":"Bulanık anılar."},{"w":"indoor","tr":"kapalı mekan / bina içi","te":"Adjective","tt":"Sıfat","de":"Happening or used inside a building","dt":"Bir binanın içinde olan veya kullanılan","e1":"Indoor sports.","e1t":"Salon (kapalı mekan) sporları.","e2":"An indoor swimming pool.","e2t":"Kapalı yüzme havuzu."},{"w":"inefficient","tr":"verimsiz / yetersiz","te":"Adjective","tt":"Sıfat","de":"Not using resources or time well","dt":"Kaynakları veya zamanı iyi kullanmayan","e1":"An inefficient heating system.","e1t":"Verimsiz bir ısıtma sistemi.","e2":"He is an inefficient worker.","e2t":"O verimsiz bir çalışandır."},{"w":"infamous","tr":"kötü şöhretli / adı çıkmış","te":"Adjective","tt":"Sıfat","de":"Famous for something considered bad","dt":"Kötü bir şeyle tanınan","e1":"An infamous criminal.","e1t":"Kötü şöhretli bir suçlu.","e2":"The infamous prison.","e2t":"Adı çıkmış hapishane."},{"w":"infantry","tr":"piyade / yaya askerler","te":"Noun","tt":"İsim","de":"Soldiers who fight on foot","dt":"Yaya olarak savaşan askerler","e1":"The infantry led the final assault.","e1t":"Son saldırıya piyadeler öncülük etti.","e2":"Infantry regiment.","e2t":"Piyade alayı."},{"w":"inferior","tr":"aşağı / kalitesiz / düşük rütbeli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Lower in rank, quality, or status","dt":"Rütbe, kalite veya statü olarak daha düşük","e1":"This model is inferior to the previous one.","e1t":"Bu model öncekinden daha kalitesiz.","e2":"To feel inferior to others.","e2t":"Kendini başkalarından aşağı hissetmek."},{"w":"infinite","tr":"sonsuz / sınırsız","te":"Adjective","tt":"Sıfat","de":"Without limits; extremely large or great","dt":"Sınırları olmayan; son derece büyük","e1":"The universe is infinite.","e1t":"Evren sonsuzdur.","e2":"With infinite patience.","e2t":"Sonsuz bir sabırla."},{"w":"inflict","tr":"(acı/ceza) çektirmek / uğratmak","te":"Verb","tt":"Fiil","de":"To force someone to experience something very unpleasant","dt":"Birini nahoş bir şeyi tecrübe etmeye zorlamak","e1":"To inflict pain on someone.","e1t":"Birine acı çektirmek.","e2":"The storm inflicted severe damage on the city.","e2t":"Fırtına şehre ağır hasar verdi (uğrattı)."},{"w":"influenza","tr":"grip","te":"Noun","tt":"İsim","de":"A common infectious disease like a very bad cold","dt":"Çok ağır bir soğuk algınlığı gibi seyreden bulaşıcı hastalık","e1":"An influenza epidemic.","e1t":"Grip salgını.","e2":"Symptoms of influenza.","e2t":"Grip belirtileri."},{"w":"informative","tr":"bilgilendirici / öğretici","te":"Adjective","tt":"Sıfat","de":"Providing a lot of useful information","dt":"Çok sayıda faydalı bilgi sağlayan","e1":"It was a very informative lecture.","e1t":"Çok bilgilendirici bir dersti.","e2":"An informative website.","e2t":"Bilgilendirici bir web sitesi."},{"w":"infrastructure","tr":"altyapı","te":"Noun","tt":"İsim","de":"The basic systems and services like roads and power","dt":"Yol ve enerji gibi temel sistem ve hizmetler","e1":"The country needs to invest in its infrastructure.","e1t":"Ülkenin altyapısına yatırım yapması gerekiyor.","e2":"Information infrastructure.","e2t":"Bilgi altyapısı."},{"w":"inhibit","tr":"engellemek / dizginlemek / yavaşlatmak","te":"Verb","tt":"Fiil","de":"To prevent something from happening or make it slower","dt":"Bir şeyin olmasını engellemek veya yavaşlatmak","e1":"High interest rates inhibit economic growth.","e1t":"Yüksek faiz oranları ekonomik büyümeyi engeller.","e2":"To inhibit a chemical reaction.","e2t":"Kimyasal bir reaksiyonu yavaşlatmak."},{"w":"inhuman","tr":"insanlık dışı / zalimce","te":"Adjective","tt":"Sıfat","de":"Extremely cruel and without pity","dt":"Son derece zalim ve acımasız","e1":"Prisoners were kept in inhuman conditions.","e1t":"Mahkumlar insanlık dışı koşullarda tutuldu.","e2":"Inhuman treatment.","e2t":"İnsanlık dışı muamele."},{"w":"initiate","tr":"başlatmak / önayak olmak / üyeliğe kabul etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cause something to begin","dt":"Bir şeyin başlamasına neden olmak","e1":"The government initiated a new program.","e1t":"Hükümet yeni bir program başlattı.","e2":"To initiate a conversation.","e2t":"Bir konuşma başlatmak."},{"w":"inmate","tr":"mahkûm / (hastane vb.) sakin","te":"Noun","tt":"İsim","de":"A person who is kept in a prison or a hospital","dt":"Hapishanede veya hastanede tutulan kişi","e1":"The inmates are demanding better food.","e1t":"Mahkumlar daha iyi yemek talep ediyor.","e2":"A prison inmate.","e2t":"Hapishane mahkumu."},{"w":"innate","tr":"doğuştan gelen / kalıtsal","te":"Adjective","tt":"Sıfat","de":"(Of a quality) which you are born with","dt":"Doğduğunuzda sahip olduğunuz (özellik)","e1":"He has an innate talent for music.","e1t":"Müziğe karşı doğuştan gelen bir yeteneği var.","e2":"Innate behavior.","e2t":"Doğuştan gelen davranış."},{"w":"inner","tr":"iç / dahili / ruhsal","te":"Adjective","tt":"Sıfat","de":"On the inside; or related to feelings","dt":"İç tarafta olan; veya duygularla ilgili","e1":"The inner ear.","e1t":"İç kulak.","e2":"Inner peace.","e2t":"İç huzur (ruhsal huzur)."},{"w":"innocence","tr":"masumiyet / suçsuzluk / saflık","te":"Noun","tt":"İsim","de":"The state of not being guilty; or lack of experience","dt":"Suçsuz olma durumu; veya deneyim eksikliği","e1":"He maintained his innocence.","e1t":"Masumiyetini savundu.","e2":"The innocence of childhood.","e2t":"Çocukluğun saflığı (masumiyeti)."},{"w":"innumerable","tr":"sayısız / çok fazla","te":"Adjective","tt":"Sıfat","de":"Too many to be counted","dt":"Sayılamayacak kadar çok","e1":"Innumerable stars in the sky.","e1t":"Gökyüzünde sayısız yıldız.","e2":"I've told him that innumerable times.","e2t":"Ona bunu sayısız kez söyledim."},{"w":"inquire","tr":"soruşturmak / bilgi istemek / sormak","te":"Verb","tt":"Fiil","de":"To ask for information","dt":"Bilgi sormak (istemek)","e1":"I'm calling to inquire about the job.","e1t":"İş hakkında bilgi almak (sormak) için arıyorum.","e2":"To inquire into a matter.","e2t":"Bir meseleyi soruşturmak."},{"w":"inscribe","tr":"kazımak / yazmak / ithaf etmek","te":"Verb","tt":"Fiil","de":"To write or cut words on something permanently","dt":"Bir şeyin üzerine kalıcı olarak kelimeler yazmak veya kazımak","e1":"His name was inscribed on the trophy.","e1t":"Adı kupaya kazınmıştı.","e2":"To inscribe a book.","e2t":"Bir kitabı (birine) ithaf ederek imzalamak."},{"w":"insecticide","tr":"böcek ilacı","te":"Noun","tt":"İsim","de":"A chemical used for killing insects","dt":"Böcekleri öldürmek için kullanılan kimyasal madde","e1":"Farmers use insecticides to protect crops.","e1t":"Çiftçiler mahsulleri korumak için böcek ilacı kullanır.","e2":"Natural insecticides.","e2t":"Doğal böcek ilaçları."},{"w":"insecure","tr":"güvensiz / emniyetsiz / özgüvensiz","te":"Adjective","tt":"Sıfat","de":"Not safe; or not confident about yourself","dt":"Güvenli olmayan; veya kendine güveni olmayan","e1":"He feels insecure about his future.","e1t":"Geleceği hakkında kendini güvensiz hissediyor.","e2":"An insecure lock.","e2t":"Emniyetsiz (gevşek) bir kilit."},{"w":"insignificant","tr":"önemsiz / anlamsız / değersiz","te":"Adjective","tt":"Sıfat","de":"Small or not important","dt":"Küçük veya önemli olmayan","e1":"The difference between the two results is insignificant.","e1t":"İki sonuç arasındaki fark önemsizdir.","e2":"An insignificant amount of money.","e2t":"Önemsiz (çok az) bir miktar para."},{"w":"insolent","tr":"küstah / terbiyesiz / saygısız","te":"Adjective","tt":"Sıfat","de":"Rude and not showing respect","dt":"Kaba ve saygı göstermeyen","e1":"An insolent child.","e1t":"Küstah bir çocuk.","e2":"Insolent remarks.","e2t":"Saygısızca (küstah) ifadeler."},{"w":"insomnia","tr":"uykusuzluk / insomni","te":"Noun","tt":"İsim","de":"The condition of being unable to sleep","dt":"Uyuyamama durumu","e1":"He suffers from chronic insomnia.","e1t":"Kronik uykusuzluk çekiyor.","e2":"To treat insomnia.","e2t":"Uykusuzluğu tedavi etmek."},{"w":"institute","tr":"enstitü / kurmak / başlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An organization for study; or to start a rule","dt":"Çalışma amaçlı kuruluş; veya bir kuralı/süreci başlatmak","e1":"The Massachusetts Institute of Technology (MIT).","e1t":"Massachusetts Teknoloji Enstitüsü.","e2":"To institute new safety measures.","e2t":"Yeni güvenlik önlemleri getirmek (başlatmak)."},{"w":"insulate","tr":"yalıtmak / izole etmek / korumak","te":"Verb","tt":"Fiil","de":"To cover something to prevent heat or sound from escaping","dt":"Isı veya sesin kaçmasını önlemek için bir şeyi kaplamak","e1":"We need to insulate the pipes.","e1t":"Boruları yalıtmamız gerekiyor.","e2":"To insulate someone from bad news.","e2t":"Birini kötü haberlerden korumak (soyutlamak)."},{"w":"intake","tr":"alım (gıda vb.) / giriş / miktar","te":"Noun","tt":"İsim","de":"The amount of something that you take into your body","dt":"Vücuda alınan bir şeyin miktarı","e1":"Daily calorie intake.","e1t":"Günlük kalori alımı.","e2":"A high intake of salt.","e2t":"Yüksek miktarda tuz alımı."},{"w":"intellect","tr":"zeka / akıl / entelektüel","te":"Noun","tt":"İsim","de":"The ability to understand and think logically","dt":"Mantıklı düşünme ve anlama yeteneği","e1":"A man of great intellect.","e1t":"Büyük zeka sahibi bir adam.","e2":"To appeal to the intellect.","e2t":"Akla hitap etmek."},{"w":"intent","tr":"niyet / amaç / niyetli","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"What you plan to do; or showing concentration","dt":"Yapmayı planladığınız şey; veya konsantrasyon gösteren","e1":"With the intent to help.","e1t":"Yardım etme niyetiyle.","e2":"He gave me an intent look.","e2t":"Bana dikkatli (kararlı) bir bakış attı."},{"w":"intercept","tr":"yolunu kesmek / durdurmak / ele geçirmek (mesaj vb.)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop something that is going from one place to another","dt":"Bir yerden bir yere giden bir şeyi durdurmak","e1":"The police intercepted the shipment.","e1t":"Polis sevkiyatın yolunu kesti (ele geçirdi).","e2":"To intercept an email.","e2t":"Bir e"},{"w":"interchange","tr":"değiş tokuş / kavşak / yer değiştirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"To exchange things with each other; or a road junction","dt":"Şeyleri birbirliyle takas etmek; veya yol kavşağı","e1":"An interchange of ideas.","e1t":"Fikir teatisinde bulunmak (fikir değiş tokuşu).","e2":"Cloverleaf interchange.","e2t":"Yonca kavşak."},{"w":"intercourse","tr":"ilişki / iletişim / cinsel ilişki","te":"Noun","tt":"İsim","de":"Communication or social connection; or sexual relations","dt":"İletişim veya sosyal bağ; veya cinsel ilişki","e1":"Social intercourse.","e1t":"Sosyal ilişki (iletişim).","e2":"Sexual intercourse.","e2t":"Cinsel ilişki."},{"w":"interior","tr":"iç / dahili / iç mekan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"The inside part of something","dt":"Bir şeyin iç kısmı","e1":"The interior of the building.","e1t":"Binanın içi.","e2":"Interior design.","e2t":"İç mimari (tasarım)."},{"w":"intermediate","tr":"orta seviye / ara","te":"Adjective/Noun/Verb","tt":"Between two levels or stages","de":"İki seviye veya aşama arasında","dt":"An intermediate English course.","e1":"Orta seviye İngilizce kursu.","e1t":"Intermediate results.","e2":"Ara sonuçlar.","e2t":""},{"w":"intimacy","tr":"samimiyet / yakınlık","te":"Noun","tt":"İsim","de":"A state of having a very close relationship","dt":"Çok yakın bir ilişkiye sahip olma durumu","e1":"A sense of intimacy.","e1t":"Bir yakınlık hissi.","e2":"They value their privacy and intimacy.","e2t":"Mahremiyetlerine ve samimiyetlerine değer veriyorlar."},{"w":"intricate","tr":"karmaşık / girift / ince işlenmiş","te":"Adjective","tt":"Sıfat","de":"Having a lot of small parts or details","dt":"Çok sayıda küçük parça veya detaya sahip olan","e1":"An intricate pattern.","e1t":"Karmaşık (ince detaylı) bir desen.","e2":"Intricate details.","e2t":"Girift detaylar."},{"w":"intrigue","tr":"entrika / ilgisini çekmek / gizli işler","te":"Noun/Verb","tt":"İsim/Fiil","de":"To make someone very interested; or a secret plan","dt":"Birinin çok ilgisini çekmek; veya gizli plan","e1":"The idea intrigues me.","e1t":"Bu fikir ilgimi çekiyor (beni cezbediyor).","e2":"Political intrigue.","e2t":"Siyasi entrika."},{"w":"introvert","tr":"içe dönük","te":"Noun/Adjective/Verb","tt":"A person who is quiet and shy","de":"Sessiz ve utangaç kişi","dt":"He is a bit of an introvert.","e1":"O biraz içe dönük biridir.","e1t":"Introvert personality.","e2":"İçe dönük kişilik.","e2t":""},{"w":"intuition","tr":"sezgi / içgüdü","te":"Noun","tt":"İsim","de":"The ability to understand something instinctively","dt":"Bir şeyi içgüdüsel olarak anlama yeteneği","e1":"I had an intuition that she was lying.","e1t":"Onun yalan söylediğine dair bir sezgim vardı.","e2":"To follow your intuition.","e2t":"Sezgilerini takip etmek."},{"w":"invalid","tr":"geçersiz / hükümsüz / hasta (bakıma muhtaç)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not legally acceptable; or a sick person","dt":"Yasal olarak kabul edilemez; veya hasta kişi","e1":"Your passport is invalid.","e1t":"Pasaportun geçersiz.","e2":"He has been an invalid since the accident.","e2t":"Kazadan beri bakıma muhtaç bir hasta."},{"w":"invaluable","tr":"paha biçilemez / çok değerli","te":"Adjective","tt":"Sıfat","de":"Extremely useful","dt":"Son derece yararlı","e1":"Her advice was invaluable to me.","e1t":"Onun tavsiyesi benim için paha biçilemezdi.","e2":"Invaluable experience.","e2t":"Çok değerli (paha biçilemez) tecrübe."},{"w":"invariable","tr":"değişmez / sabit","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Always staying the same","dt":"Her zaman aynı kalan","e1":"His invariable routine.","e1t":"Onun hiç değişmeyen rutini.","e2":"Invariable laws of nature.","e2t":"Doğanın değişmez yasaları."},{"w":"inverse","tr":"ters / zıt","te":"Adjective/Noun/Verb","tt":"Opposite in relation to something else","de":"Başka bir şeye göre zıt ilişkide olan","dt":"There is an inverse relationship between price and demand.","e1":"Fiyat ve talep arasında ters bir ilişki vardır.","e1t":"The inverse of a number.","e2":"Bir sayının tersi.","e2t":""},{"w":"invincible","tr":"yenilmez / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"Impossible to defeat or prevent","dt":"Yenilmesi veya engellenmesi imkansız","e1":"An invincible army.","e1t":"Yenilmez bir ordu.","e2":"He felt invincible after the win.","e2t":"Galibiyetten sonra kendini yenilmez hissetti."},{"w":"involuntary","tr":"istemsiz / elinde olmadan","te":"Adjective","tt":"Sıfat","de":"Done without intention or control","dt":"Niyet veya kontrol olmadan yapılan","e1":"An involuntary smile.","e1t":"İstem dışı (elinde olmayan) bir gülümseme.","e2":"Involuntary muscles.","e2t":"İstem dışı çalışan kaslar."},{"w":"irrational","tr":"mantıksız / rasyonel olmayan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not based on clear thought or reason","dt":"Net bir düşünce veya mantığa dayanmayan","e1":"An irrational fear of spiders.","e1t":"Mantıksız bir örümcek korkusu.","e2":"Irrational behavior.","e2t":"Mantıksız davranış."},{"w":"irreparable","tr":"onarılamaz / tamir edilemez","te":"Adjective","tt":"Sıfat","de":"(Of damage) impossible to repair","dt":"(Hasar için) tamir edilmesi imkansız","e1":"The accident caused irreparable damage to the car.","e1t":"Kaza arabada onarılamaz bir hasara yol açtı.","e2":"Irreparable loss.","e2t":"Telafisi olmayan kayıp."},{"w":"irresistible","tr":"karşı konulamaz / dayanılmaz","te":"Adjective","tt":"Sıfat","de":"Impossible to refuse or oppose","dt":"Reddedilmesi veya karşı çıkılması imkansız","e1":"An irresistible offer.","e1t":"Karşı konulamaz bir teklif.","e2":"Irresistible chocolate cake.","e2t":"Dayanılmaz çikolatalı kek."},{"w":"irresponsible","tr":"sorumsuz","te":"Adjective","tt":"Sıfat","de":"Not thinking about the results of your actions","dt":"Eylemlerinizin sonuçlarını düşünmeyen","e1":"It was irresponsible of you to leave the door open.","e1t":"Kapıyı açık bırakman sorumsuzluktu.","e2":"Irresponsible behavior.","e2t":"Sorumsuz davranış."},{"w":"irreversible","tr":"geri döndürülemez / değiştirilemez","te":"Adjective","tt":"Sıfat","de":"Impossible to change back to a previous state","dt":"Önceki bir duruma döndürülmesi imkansız","e1":"Climate change may be irreversible.","e1t":"İklim değişikliği geri döndürülemez olabilir.","e2":"An irreversible decision.","e2t":"Geri dönüşü olmayan bir karar."},{"w":"irritable","tr":"asabi / sinirli / çabuk kızan","te":"Adjective","tt":"Sıfat","de":"Becoming annoyed or angry very easily","dt":"Çok kolay sinirlenen veya kızan","e1":"He is very irritable in the mornings.","e1t":"Sabahları çok asabi olur.","e2":"An irritable mood.","e2t":"Sinirli bir ruh hali."},{"w":"isolate","tr":"izole etmek / soyutlamak / ayırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To separate someone or something from others","dt":"Birini veya bir şeyi diğerlerinden ayırmak","e1":"Patients with the virus were isolated.","e1t":"Virüslü hastalar izole edildi.","e2":"To isolate a variable in math.","e2t":"Matematikte bir değişkeni yalnız bırakmak."},{"w":"itemize","tr":"maddeler halinde sıralamak / kalem kalem yazmak","te":"Verb","tt":"Fiil","de":"To list things separately","dt":"Şeyleri ayrı ayrı listelemek","e1":"Please itemize your expenses for the trip.","e1t":"Lütfen seyahat masraflarınızı kalem kalem listeleyin.","e2":"An itemized bill.","e2t":"Ayrıntılı (madde madde) fatura."},{"w":"itinerary","tr":"seyahat programı / yol güzergahı","te":"Noun","tt":"İsim","de":"A detailed plan or route of a journey","dt":"Bir yolculuğun detaylı planı veya rotası","e1":"We have a very busy itinerary for our tour of Turkey.","e1t":"Türkiye turumuz için çok yoğun bir seyahat programımız var.","e2":"To follow the itinerary.","e2t":"Güzergahı takip etmek."},{"w":"jargon","tr":"mesleki dil / jargon","te":"Noun","tt":"İsim","de":"Special words used by a particular group of people","dt":"Belirli bir grup tarafından kullanılan özel kelimeler","e1":"I don't understand computer jargon.","e1t":"Bilgisayar jargonundan anlamıyorum.","e2":"Legal jargon.","e2t":"Hukuki terimler (jargon)."},{"w":"jolly","tr":"neşeli / keyifli / çok","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Happy and cheerful","dt":"Mutlu ve neşeli","e1":"A jolly old man.","e1t":"Neşeli bir ihtiyar.","e2":"Everyone was in a jolly mood.","e2t":"Herkes neşeli bir ruh halindeydi."},{"w":"journalism","tr":"gazetecilik","te":"Noun","tt":"İsim","de":"The work of collecting and writing news stories","dt":"Haber toplama ve yazma işi","e1":"He wants to pursue a career in journalism.","e1t":"Gazetecilik alanında kariyer yapmak istiyor.","e2":"Investigative journalism.","e2t":"Araştırmacı gazetecilik."},{"w":"judicial","tr":"adli / yargısal / hukuki","te":"Adjective","tt":"Sıfat","de":"Relating to a court or a judge","dt":"Bir mahkeme veya yargıç ile ilgili","e1":"The judicial system.","e1t":"Yargı sistemi.","e2":"Judicial review.","e2t":"Yargısal denetim."},{"w":"jurisdiction","tr":"yargı yetkisi / yetki alanı","te":"Noun","tt":"İsim","de":"The official power to make legal decisions","dt":"Hukuki kararlar verme resmi gücü","e1":"This matter is outside our jurisdiction.","e1t":"Bu mesele bizim yetki alanımızın dışındadır.","e2":"Territorial jurisdiction.","e2t":"Bölgesel yetki alanı."},{"w":"justification","tr":"gerekçe / haklı çıkarma","te":"Noun","tt":"İsim","de":"A good reason for something","dt":"Bir şey için geçerli bir sebep","e1":"There is no justification for such violence.","e1t":"Bu tür bir şiddetin hiçbir gerekçesi olamaz.","e2":"To provide a justification.","e2t":"Bir gerekçe sunmak."},{"w":"juvenile","tr":"genç / çocuksu / reşit olmayan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to young people; or silly","dt":"Gençlerle ilgili; veya çocuksu/aptalca","e1":"Juvenile crime.","e1t":"Gençlik suçları.","e2":"A juvenile sense of humor.","e2t":"Çocuksu bir mizah anlayışı."},{"w":"kernel","tr":"çekirdek / öz / tane","te":"Noun","tt":"İsim","de":"The inner part of a nut; or the most important part","dt":"Kuruyemişin iç kısmı; veya en önemli kısım (öz)","e1":"A kernel of corn.","e1t":"Mısır tanesi.","e2":"There is a kernel of truth in his story.","e2t":"Hikayesinde bir gerçeklik payı (özü) var."},{"w":"kin","tr":"akraba / soy","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Your family or relatives","dt":"Aileniz veya akrabalarınız","e1":"Next of kin (closest relative).","e1t":"En yakın akraba.","e2":"They are my kith and kin.","e2t":"Onlar benim hısım akrabamdır."},{"w":"kinetic","tr":"hareketli / kinetik","te":"Adjective","tt":"Sıfat","de":"Relating to motion","dt":"Hareket ile ilgili","e1":"Kinetic energy.","e1t":"Kinetik enerji.","e2":"Kinetic art.","e2t":"Hareketli sanat."},{"w":"knack","tr":"yetenek / püf noktası / beceri","te":"Noun","tt":"İsim","de":"A special skill or ability to do something easily","dt":"Bir şeyi kolayca yapma becerisi veya yeteneği","e1":"He has a knack for making people laugh.","e1t":"İnsanları güldürme konusunda bir yeteneği var.","e2":"The knack of the trade.","e2t":"İşin püf noktası."},{"w":"knob","tr":"tokmak / düğme / kulp","te":"Noun","tt":"İsim","de":"A round handle or control button","dt":"Yuvarlak kulp veya kontrol düğmesi","e1":"Turn the knob clockwise.","e1t":"Düğmeyi saat yönünde çevirin.","e2":"Door knob.","e2t":"Kapı tokmağı."},{"w":"lace","tr":"dantel / bağcık / bağlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A decorative cloth with small holes; or string for shoes","dt":"Küçük delikleri olan süslü kumaş; veya ayakkabı bağı","e1":"A white lace dress.","e1t":"Beyaz dantelli bir elbise.","e2":"Tie your shoe laces.","e2t":"Ayakkabı bağcıklarını bağla."},{"w":"landlord","tr":"ev sahibi / mülk sahibi","te":"Noun","tt":"İsim","de":"A person who rents out a building or land","dt":"Bir bina veya araziyi kiralayan kişi","e1":"Our landlord is very helpful.","e1t":"Ev sahibimiz çok yardımseverdir.","e2":"Landlord and tenant.","e2t":"Ev sahibi ve kiracı."},{"w":"landmark","tr":"simge yapı / dönüm noktası","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A building or event that is easily recognized","dt":"Kolayca tanınan bina veya olay","e1":"The Galata Tower is a famous landmark.","e1t":"Galata Kulesi ünlü bir simge yapıdır.","e2":"A landmark decision.","e2t":"Dönüm noktası niteliğinde bir karar."},{"w":"lane","tr":"şerit / yol / patika","te":"Noun","tt":"İsim","de":"A narrow road; or a part of a main road","dt":"Dar yol; veya ana yolun bir bölümü","e1":"Emergency lane.","e1t":"Emniyet şeridi.","e2":"A country lane.","e2t":"Bir köy yolu (patika)."},{"w":"lap","tr":"kucak / tur (yarış) / yalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The top part of your legs when sitting; or one journey around a track","dt":"Otururken bacakların üst kısmı; veya pist etrafındaki bir tur","e1":"The baby fell asleep on her lap.","e1t":"Bebek dizinde (kucağında) uyuyakaldı.","e2":"He completed the final lap.","e2t":"Son turu tamamladı."},{"w":"lapse","tr":"hata / zaman aşımı / kesinti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A temporary failure; or a period of time passing","dt":"Geçici bir hata; veya zaman geçmesi","e1":"A lapse of memory.","e1t":"Hafıza kaybı (anlık unutma).","e2":"After a lapse of two years.","e2t":"İki yıllık bir aradan (zaman geçmesinden) sonra."},{"w":"larva","tr":"larva / kurtçuk","te":"Noun","tt":"İsim","de":"A young insect that looks like a worm","dt":"Solucana benzeyen genç böcek hali","e1":"The larva develops into a butterfly.","e1t":"Larva bir kelebeğe dönüşür.","e2":"Mosquito larvae.","e2t":"Sivrisinek larvaları."},{"w":"laser","tr":"lazer","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A powerful beam of light","dt":"Güçlü ışık demeti","e1":"Laser surgery.","e1t":"Lazer ameliyatı.","e2":"A laser printer.","e2t":"Lazer yazıcı."},{"w":"lash","tr":"kırbaçlamak / kirpik / sertçe vurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit with a whip; or a hair on the eyelid","dt":"Kırbaçla vurmak; veya göz kapağındaki kıl","e1":"Rain lashed against the window.","e1t":"Yağmur pencereye sertçe vurdu.","e2":"Eye lashes.","e2t":"Kirpikler."},{"w":"lasting","tr":"kalıcı / dayanıklı","te":"Adjective","tt":"Sıfat","de":"Continuing to exist for a long time","dt":"Uzun süre var olmaya devam eden","e1":"A lasting peace.","e1t":"Kalıcı bir barış.","e2":"To make a lasting impression.","e2t":"Kalıcı bir izlenim bırakmak."},{"w":"latent","tr":"gizli / örtük / henüz ortaya çıkmamış","te":"Adjective","tt":"Sıfat","de":"Present but not yet active or visible","dt":"Var olan ama henüz aktif veya görünür olmayan","e1":"Latent talent.","e1t":"Gizli yetenek.","e2":"Latent heat.","e2t":"Gizli ısı."},{"w":"latitude","tr":"enlem / serbestlik","te":"Noun","tt":"Isim","de":"The distance north or south of the equator; or freedom","dt":"Ekvatorun kuzey veya güneyindeki mesafe; veya hareket serbestliği","e1":"High latitudes.","e1t":"Yüksek enlemler.","e2":"Courts have some latitude in sentencing.","e2t":"Mahkemelerin cezalandırma konusunda biraz serbestliği (takdir yetkisi) vardır."},{"w":"lavatory","tr":"tuvalet / hela","te":"Noun","tt":"İsim","de":"A toilet or a room containing a toilet","dt":"Tuvalet veya tuvaletin bulunduğu oda","e1":"The lavatory is at the end of the hall.","e1t":"Tuvalet koridorun sonundadır.","e2":"Public lavatory.","e2t":"Genel tuvalet."},{"w":"lawn","tr":"çim / çimlik alan","te":"Noun","tt":"İsim","de":"An area of short grass in a garden","dt":"Bahçedeki kısa kesilmiş çimenlik alan","e1":"I need to mow the lawn.","e1t":"Çimleri biçmem gerekiyor.","e2":"To sit on the lawn.","e2t":"Çimenlerin üzerinde oturmak."},{"w":"layman","tr":"maalesef (uzman olmayan) / sıradan kişi","te":"Noun","tt":"İsim","de":"A person who does not have expert knowledge","dt":"Uzmanlık bilgisi olmayan kişi","e1":"In layman's terms (simply).","e1t":"Sıradan birinin anlayacağı dille (basitçe).","e2":"To explain science to the layman.","e2t":"Bilimi uzman olmayana açıklamak."},{"w":"ledger","tr":"defter","te":"i kebir / kayıt defteri","tt":"Noun","de":"İsim","dt":"A book in which a bank or business records money","e1":"Bir banka veya işletmenin para kayıtlarını tuttuğu defter","e1t":"To enter transactions in a ledger.","e2":"İşlemleri bir deftere kaydetmek.","e2t":"General ledger."},{"w":"legible","tr":"okunabilir","te":"Adjective","tt":"Sıfat","de":"(Of writing) clear enough to be read","dt":"(Yazı için) okunabilecek kadar net","e1":"Her handwriting is barely legible.","e1t":"El yazısı zar zor okunuyor.","e2":"Legible signature.","e2t":"Okunabilir imza."},{"w":"legislate","tr":"yasa yapmak / yasalaştırmak","te":"Verb","tt":"Fiil","de":"To make a law or laws","dt":"Yasa veya yasalar yapmak","e1":"The government decided to legislate against smoking.","e1t":"Hükümet sigara karşıtı yasa yapmaya karar verdi.","e2":"To legislate for change.","e2t":"Değişim için yasalaştırmak."},{"w":"liaison","tr":"irtibat / işbirliği / yasak ilişki","te":"Noun","tt":"İsim","de":"Communication between people or groups; or a secret relationship","dt":"İnsanlar veya gruplar arası iletişim; veya gizli ilişki","e1":"He acts as a liaison between the two schools.","e1t":"İki okul arasında irtibat görevlisi olarak çalışıyor.","e2":"To work in close liaison with...","e2t":"... ile yakın işbirliği içinde çalışmak."},{"w":"liberate","tr":"özgürleştirmek / kurtarmak","te":"Verb","tt":"Fiil","de":"To help someone or a country to be free","dt":"Birinin veya bir ülkenin özgür olmasına yardım etmek","e1":"The army liberated the city.","e1t":"Ordu şehri kurtardı (özgürleştirdi).","e2":"To liberate someone from prison.","e2t":"Birini hapisten kurtarmak."},{"w":"lieutenant","tr":"teğmen / yardımcı","te":"Noun","tt":"İsim","de":"A low","dt":"ranking officer in the army; or an assistant","e1":"Orduda düşük rütbeli subay; veya yardımcı","e1t":"He was promoted to lieutenant.","e2":"Teğmenliğe terfi etti.","e2t":"One of the leader's top lieutenants."},{"w":"lifespan","tr":"ömür / yaşam süresi","te":"Noun","tt":"İsim","de":"The length of time for which a person or animal lives","dt":"Bir insanın veya hayvanın yaşadığı süre","e1":"The average human lifespan has increased.","e1t":"Ortalama insan ömrü arttı.","e2":"The lifespan of a battery.","e2t":"Bir pilin kullanım ömrü."},{"w":"likelihood","tr":"olasılık / ihtimal","te":"Noun","tt":"İsim","de":"The chance that something will happen","dt":"Bir şeyin olma şansı","e1":"There is every likelihood that he will win.","e1t":"Kazanma ihtimali her bakımdan çok yüksek.","e2":"In all likelihood.","e2t":"Büyük ihtimalle."},{"w":"limestone","tr":"kireçtaşı / kalker","te":"Noun","tt":"İsim","de":"A white or grey rock used in building and making cement","dt":"İnşaatta ve çimento yapımında kullanılan beyaz veya gri kaya","e1":"The hills are made of limestone.","e1t":"Tepeler kireçtaşından oluşmuştur.","e2":"Limestone caves.","e2t":"Kireçtaşı mağaraları."},{"w":"lineage","tr":"soy / köken / nesil","te":"Noun","tt":"İsim","de":"The series of people that someone is descended from","dt":"Birinin soyundan geldiği insanlar silsilesi","e1":"He can trace his lineage back to the 18th century.","e1t":"Soyunu 18. yüzyıla kadar takip edebiliyor.","e2":"Ancient lineage.","e2t":"Kadim soy."},{"w":"linguistic","tr":"dilbilimsel / dille ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to language or linguistics","dt":"Dil veya dilbilim ile ilgili","e1":"Linguistic skills.","e1t":"Dil becerileri.","e2":"Linguistic diversity.","e2t":"Dilsel çeşitlilik."},{"w":"liquidate","tr":"tasfiye etmek / borç ödemek / (birini) ortadan kaldırmak","te":"Verb","tt":"Fiil","de":"To close a business; to pay a debt; or to kill","dt":"Bir işletmeyi kapatmak; borç ödemek; veya öldürmek","e1":"The company was liquidated.","e1t":"Şirket tasfiye edildi.","e2":"To liquidate assets.","e2t":"Varlıkları nakde çevirmek (tasfiye etmek)."},{"w":"liquor","tr":"içki / sert alkollü içki","te":"Noun","tt":"İsim","de":"Strong alcoholic drink","dt":"Sert alkollü içecek","e1":"Hard liquor like vodka or whiskey.","e1t":"Votka veya viski gibi sert içkiler.","e2":"Liquor store.","e2t":"İçki dükkanı (tekel)."},{"w":"literate","tr":"okuryazar / bilgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to read and write; or having knowledge","dt":"Okuma yazma bilen; veya bilgili","e1":"Computer literate.","e1t":"Bilgisayar kullanmayı bilen (bilgili).","e2":"A highly literate society.","e2t":"Okuryazarlık oranı yüksek bir toplum."},{"w":"liver","tr":"karaciğer","te":"Noun","tt":"İsim","de":"A large organ in the body that cleans the blood","dt":"Vücutta kanı temizleyen büyük organ","e1":"Liver failure.","e1t":"Karaciğer yetmezliği.","e2":"Fatty liver.","e2t":"Karaciğer yağlanması."},{"w":"loathe","tr":"tiksinmek / nefret etmek","te":"Verb","tt":"Fiil","de":"To hate someone or something very much","dt":"Birinden veya bir şeyden çok nefret etmek","e1":"I absolutely loathe spiders.","e1t":"Örümceklerden kesinlikle nefret ederim (tiksinirim).","e2":"They loathe each other.","e2t":"Birbirlerinden nefret ediyorlar."},{"w":"lobby","tr":"lobi / bekleme salonu / kulis yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large entrance area; or to try to influence politicians","dt":"Geniş giriş alanı; veya politikacıları etkilemeye çalışmak","e1":"I'll meet you in the hotel lobby.","e1t":"Seninle otel lobisinde buluşacağız.","e2":"They are lobbying for tax reform.","e2t":"Vergi reformu için lobi yapıyorlar (kulis yapıyorlar)."},{"w":"locomotive","tr":"lokomotif / çekici güç","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An engine that pulls a train","dt":"Treni çeken motor","e1":"A steam locomotive.","e1t":"Buharlı lokomotif.","e2":"The locomotive of economic growth.","e2t":"Ekonomik büyümenin lokomotifi (çekici gücü)."},{"w":"loft","tr":"çatı katı / tavan arası","te":"Noun/Verb","tt":"İsim/Fiil","de":"A space under the roof of a house","dt":"Bir evin çatısının altındaki alan","e1":"We converted the loft into a bedroom.","e1t":"Tavan arasını yatak odasına dönüştürdük.","e2":"A loft apartment.","e2t":"Çatı katı dairesi."},{"w":"log","tr":"kütük / kayıt / günlük tutmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thick piece of wood; or a formal record","dt":"Kalın odun parçası; veya resmi kayıt","e1":"Put another log on the fire.","e1t":"Ateşe bir kütük daha at.","e2":"Ships must keep a daily log.","e2t":"Gemiler günlük seyir defteri (kayıt) tutmalıdır."},{"w":"longevity","tr":"uzun ömürlülük / uzun ömür","te":"Noun","tt":"İsim","de":"Long life; or the length of a life","dt":"Uzun yaşam; veya yaşam süresi","e1":"Healthy diet contributes to longevity.","e1t":"Sağlıklı beslenme uzun ömre katkıda bulunur.","e2":"The longevity of a career.","e2t":"Bir kariyerin uzun süreli olması."},{"w":"longitude","tr":"boylam","te":"Noun","tt":"İsim","de":"The distance east or west of the prime meridian","dt":"Başlangıç meridyeninin doğusundaki veya batısındaki mesafe","e1":"What is the latitude and longitude of Istanbul?","e1t":"İstanbul'un enlemi ve boylamı nedir?","e2":"Lines of longitude.","e2t":"Boylam çizgileri."},{"w":"lookout","tr":"gözcü / gözetleme yeri / görüş","te":"Noun","tt":"İsim","de":"A person who watches for danger; or a place for watching","dt":"Tehlikeyi izleyen kişi veya izleme yeri","e1":"One of the burglars acted as a lookout.","e1t":"Hırsızlardan biri gözcü olarak görev yaptı.","e2":"Keep a sharp lookout for suspicious activity.","e2t":"Şüpheli hareketlere karşı tetikte (gözcüde) olun."},{"w":"loom","tr":"(tehlike vb.) belirmek / dokuma tezgahı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To appear as a large, often frightening shape; or a weaving machine","dt":"Büyük ve korkutucu bir şekilde belirmek; veya dokuma tezgahı","e1":"A dark shape loomed out of the fog.","e1t":"Sisten koyu bir karaltı belirdi.","e2":"A crisis is looming on the horizon.","e2t":"Ufukta bir kriz beliriyor."},{"w":"loop","tr":"döngü / ilmek / kavis","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shape like a curve or circle; or a repeating sequence","dt":"Eğri veya daire şekli; veya kendini tekrar eden dizi","e1":"The computer program got stuck in a loop.","e1t":"Bilgisayar programı bir döngüde takılı kaldı.","e2":"An infinite loop.","e2t":"Sonsuz döngü."},{"w":"loot","tr":"yağmalamak / ganimet / çalmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To steal from shops or houses during a war or riot","dt":"Savaş veya isyan sırasında dükkan veya evlerden çalmak","e1":"Shops were looted during the riot.","e1t":"İsyan sırasında dükkanlar yağmalandı.","e2":"To carry off the loot.","e2t":"Ganimeti alıp götürmek."},{"w":"lopsided","tr":"orantısız / bir yana yatık","te":"Adjective","tt":"Sıfat","de":"Having one side lower, smaller, or heavier than the other","dt":"Bir tarafı diğerinden daha alçak, küçük veya ağır olan","e1":"A lopsided grin.","e1t":"Yamuk (bir yana yatık) bir sırıtış.","e2":"The game was a lopsided contest.","e2t":"Maç orantısız (tek taraflı) bir mücadeleydi."},{"w":"lottery","tr":"piyango / şans işi","te":"Noun","tt":"İsim","de":"A game of chance in which people win prizes; or a situation of luck","dt":"İnsanların ödül kazandığı şans oyunu; veya şans durumu","e1":"He won the national lottery.","e1t":"Milli piyangoyu kazandı.","e2":"Life is often a lottery.","e2t":"Hayat genellikle bir şans işidir (piyangodur)."},{"w":"lucrative","tr":"kârlı / kazançlı","te":"Adjective","tt":"Sıfat","de":"Producing a lot of money","dt":"Çok para getiren","e1":"A lucrative business deal.","e1t":"Kârlı bir iş anlaşması.","e2":"Scuba diving can be a lucrative profession.","e2t":"Tüplü dalış kazançlı bir meslek olabilir."},{"w":"ludicrous","tr":"gülünç / saçma","te":"Adjective","tt":"Sıfat","de":"Stupid or unreasonable and deserving to be laughed at","dt":"Aptalca veya mantıksız ve gülünç olan","e1":"It’s a ludicrous suggestion.","e1t":"Bu gülünç (saçma) bir öneri.","e2":"He looked ludicrous in that hat.","e2t":"O şapkayla gülünç görünüyordu."},{"w":"lull","tr":"sakinleşmek / nenni / geçici sessizlik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cause someone to feel calm; or a quiet period","dt":"Birini sakinleştirmek; veya sessiz bir dönem","e1":"The sound of the rain lulled him to sleep.","e1t":"Yağmurun sesi onu uyuttu (sakinleştirdi).","e2":"A lull in the conversation.","e2t":"Konuşmadaki geçici sessizlik."},{"w":"lunatic","tr":"deli / çılgın / kaçık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who behaves in a very foolish or dangerous way","dt":"Çok aptalca veya tehlikeli davranan kişi","e1":"He drives like a lunatic.","e1t":"Deli gibi araba sürüyor.","e2":"A lunatic idea.","e2t":"Çılgınca (kaçıkça) bir fikir."},{"w":"lure","tr":"cezbetmek / yem / çekicilik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To persuade someone to go somewhere by offering a reward","dt":"Bir ödül sunarak birini bir yere gitmeye ikna etmek","e1":"The promise of high wages lured him to the city.","e1t":"Yüksek ücret vaadi onu şehre çekti (cezbetti).","e2":"A fishing lure.","e2t":"Balık yemi."},{"w":"lush","tr":"gür (bitki) / lüks / bereketli","te":"Adjective","tt":"Sıfat","de":"Having a lot of healthy green plants; or luxurious","dt":"Çok sayıda sağlıklı yeşil bitkisi olan; veya lüks","e1":"A lush green garden.","e1t":"Gür yeşil bir bahçe.","e2":"Lush vegetation.","e2t":"Gür bitki örtüsü."},{"w":"lust","tr":"şehvet / güçlü istek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very strong sexual desire; or a strong wish for something","dt":"Çok güçlü cinsel arzu; veya bir şey için güçlü istek","e1":"A lust for power.","e1t":"Güç tutkusu (isteği).","e2":"Driven by lust.","e2t":"Şehvetle hareket eden."},{"w":"luxurious","tr":"lüks / konforlu","te":"Adjective","tt":"Sıfat","de":"Very comfortable and expensive","dt":"Çok rahat ve pahalı","e1":"A luxurious hotel room.","e1t":"Lüks bir otel odası.","e2":"To lead a luxurious life.","e2t":"Lüks bir hayat sürmek."},{"w":"magistrate","tr":"sulh hakimi / yargıç","te":"Noun","tt":"İsim","de":"A judge who deals with less serious crimes","dt":"Daha az ciddi suçlarla ilgilenen yargıç","e1":"He was brought before a magistrate.","e1t":"Sulh hakiminin huzuruna çıkarıldı.","e2":"Examining magistrate.","e2t":"Sorgu hakimi."},{"w":"magnet","tr":"mıknatıs / çekim merkezi","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object that attracts metal; or something that attracts people","dt":"Metali çeken nesne; veya insanları çeken şey","e1":"The city is a magnet for tourists.","e1t":"Şehir turistler için bir çekim merkezidir (mıknatıstır).","e2":"A fridge magnet.","e2t":"Buzdolabı mıknatısı."},{"w":"magnify","tr":"büyütmek / abartmak","te":"Verb","tt":"Fiil","de":"To make something look larger; or to make something seem more important","dt":"Bir şeyi daha büyük göstermek; veya daha önemli göstermek","e1":"Use a magnifying glass to read the small print.","e1t":"Küçük yazıları okumak için büyüteç kullanın.","e2":"To magnify the problem.","e2t":"Sorunu abartmak."},{"w":"maiden","tr":"ilk / bakire / genç kız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Being the first of its kind; or an unmarried girl","dt":"Türünün ilki olan; veya evlenmemiş kız","e1":"The ship’s maiden voyage.","e1t":"Geminin ilk seferi.","e2":"Maiden name.","e2t":"Kızlık soyadı."},{"w":"mainland","tr":"anakara","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The main part of a country, not including the islands","dt":"Bir ülkenin adalar dışındaki ana kısmı","e1":"We took a ferry from the island to the mainland.","e1t":"Adadan anakaraya bir feribotla geçtik.","e2":"Mainland Greece.","e2t":"Yunanistan anakarası."},{"w":"majestic","tr":"görkemli / azametli / şahane","te":"Adjective","tt":"Sıfat","de":"Beautiful, powerful, or causing great admiration","dt":"Güzel, güçlü veya büyük hayranlık uyandıran","e1":"The majestic peaks of the Alps.","e1t":"Alplerin görkemli zirveleri.","e2":"A majestic performance.","e2t":"Şahane (azametli) bir performans."},{"w":"malady","tr":"hastalık / dert","te":"Noun","tt":"İsim","de":"A disease or a serious problem","dt":"Bir hastalık veya ciddi bir sorun","e1":"A mysterious malady.","e1t":"Gizemli bir hastalık.","e2":"Violent crime is a malady of modern society.","e2t":"Şiddet içeren suçlar modern toplumun bir derdidir (hastalığıdır)."},{"w":"malaria","tr":"sıtma","te":"Noun","tt":"İsim","de":"A serious disease spread by mosquitoes","dt":"Sivrisinekler tarafından yayılan ciddi bir hastalık","e1":"He contracted malaria in Africa.","e1t":"Afrika'da sıtmaya yakalandı.","e2":"Malaria treatment.","e2t":"Sıtma tedavisi."},{"w":"malevolent","tr":"kötü niyetli / art niyetli","te":"Adjective","tt":"Sıfat","de":"Wanting to cause harm or evil to others","dt":"Başkalarına zarar vermek veya kötülük yapmak isteyen","e1":"A malevolent look.","e1t":"Kötü niyetli bir bakış.","e2":"Malevolent influence.","e2t":"Kötü niyetli etki."},{"w":"malfunction","tr":"arıza / bozukluk / hata yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A failure to work correctly","dt":"Doğru çalışmama durumu","e1":"A technical malfunction.","e1t":"Teknik bir arıza.","e2":"The equipment malfunctioned.","e2t":"Ekipman arızalandı."},{"w":"malice","tr":"kötü niyet / hınç / garez","te":"Noun","tt":"İsim","de":"The wish to harm or upset someone","dt":"Birine zarar verme veya onu üzme isteği","e1":"He acted without malice.","e1t":"Kötü niyet olmadan hareket etti.","e2":"To bear malice toward someone.","e2t":"Birine karşı garez (hınç) beslemek."},{"w":"malignant","tr":"kötü huylu / zararlı","te":"Adjective","tt":"Sıfat","de":"(Of a disease) harmful and likely to cause death","dt":"(Hastalık için) zararlı ve ölüme neden olabilen","e1":"A malignant tumor.","e1t":"Kötü huylu tümör.","e2":"Malignant intentions.","e2t":"Kötü niyetler."},{"w":"mammal","tr":"memeli","te":"Noun","tt":"İsim","de":"An animal that feeds its young with milk","dt":"Yavrularını sütle besleyen hayvan","e1":"Whales are mammals.","e1t":"Balinalar memelidir.","e2":"Marine mammals.","e2t":"Deniz memelileri."},{"w":"manageable","tr":"yönetilebilir / başa çıkılabilir","te":"Adjective","tt":"Sıfat","de":"Easy to deal with or control","dt":"Başa çıkması veya kontrol etmesi kolay","e1":"The task is quite manageable.","e1t":"Görev oldukça yönetilebilir (kolay).","e2":"To keep the debt at a manageable level.","e2t":"Borcu yönetilebilir bir seviyede tutmak."},{"w":"mandate","tr":"yetki / zorunlu kılmak / görevlendirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Official permission; or to order someone to do something","dt":"Resmi izin (yetki); veya birine bir şeyi yapmasını emretmek","e1":"The government has a mandate to reform the law.","e1t":"Hükümetin yasayı reforme etme yetkisi var.","e2":"To mandate masks in schools.","e2t":"Okullarda maskeyi zorunlu kılmak."},{"w":"maneuver / manoeuvre","tr":"manevra / manevra yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A clever or skillful movement; or a plan","dt":"Zekice veya becerikli hareket; veya plan","e1":"A difficult parking maneuver.","e1t":"Zorlu bir park manevrası.","e2":"To maneuver through traffic.","e2t":"Trafikte manevra yaparak ilerlemek."},{"w":"manifestation","tr":"tezahür / gösterge / belirti","te":"Noun","tt":"İsim","de":"A sign that shows something clearly","dt":"Bir şeyi net bir şekilde gösteren işaret","e1":"The manifestation of symptoms.","e1t":"Belirtilerin (semptomların) ortaya çıkışı (tezahürü).","e2":"A clear manifestation of public anger.","e2t":"Halkın öfkesinin açık bir göstergesi."},{"w":"mankind","tr":"insanlık / beşeriyet","te":"Noun","tt":"İsim","de":"All humans as a group","dt":"Grup olarak tüm insanlar","e1":"The history of mankind.","e1t":"İnsanlık tarihi.","e2":"For the benefit of all mankind.","e2t":"Tüm insanlığın yararı için."},{"w":"manor","tr":"malikâne / köşk","te":"Noun","tt":"İsim","de":"A large country house with land","dt":"Arazisi olan büyük köy evi","e1":"The lord of the manor.","e1t":"Malikâne sahibi (lord).","e2":"An old stone manor house.","e2t":"Eski taştan bir malikâne."},{"w":"mansion","tr":"köşk / konak / saray yavrusu","te":"Noun","tt":"İsim","de":"A very large and expensive house","dt":"Çok büyük ve pahalı ev","e1":"He lives in a 20","e1t":"room mansion.","e2":"20 odalı bir konakta yaşıyor.","e2t":"Luxury mansions."},{"w":"maple","tr":"akçaağaç","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A tree with shaped leaves that turn red in autumn","dt":"Sonbaharda kırmızıya dönen yaprakları olan ağaç","e1":"Maple syrup.","e1t":"Akçaağaç şurubu.","e2":"A leaf of a maple tree.","e2t":"Akçaağaç yaprağı."},{"w":"marginal","tr":"marjinal / önemsiz / sınırda","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Small and not important; or on the edge","dt":"Küçük ve önemsiz; veya sınırda/kenarda","e1":"A marginal improvement.","e1t":"Çok az (marjinal) bir iyileşme.","e2":"Marginal groups in society.","e2t":"Toplumdaki marjinal gruplar."},{"w":"marital","tr":"evlilikle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to marriage","dt":"Evlilik ile ilgili","e1":"Marital status.","e1t":"Medeni durum.","e2":"Marital problems.","e2t":"Evlilikle ilgili sorunlar."},{"w":"maritime","tr":"denizcilikle ilgili / denizel","te":"Adjective","tt":"Sıfat","de":"Relating to the sea or ships","dt":"Deniz veya gemilerle ilgili","e1":"Maritime law.","e1t":"Deniz hukuku.","e2":"Maritime museum.","e2t":"Denizcilik müzesi."},{"w":"markedly","tr":"belirgin şekilde / göze çarpar şekilde","te":"Adverb","tt":"Zarf","de":"In a very clear and noticeable way","dt":"Çok net ve fark edilir bir şekilde","e1":"The situation has improved markedly.","e1t":"Durum belirgin şekilde iyileşti.","e2":"His behavior changed markedly.","e2t":"Davranışı göze çarpar şekilde değişti."},{"w":"marketplace","tr":"pazar yeri / piyasa","te":"Noun","tt":"İsim","de":"A place where things are bought and sold; or world of business","dt":"Şeylerin alınıp satıldığı yer; veya iş dünyası","e1":"A global marketplace.","e1t":"Küresel piyasa.","e2":"To bring a product to the marketplace.","e2t":"Bir ürünü piyasaya sürmek."},{"w":"marsh","tr":"bataklık / sazlık","te":"Noun","tt":"İsim","de":"Ground near a lake or river that is always wet","dt":"Göl veya nehir yakınındaki her zaman ıslak olan yer","e1":"The cows were grazing in the marsh.","e1t":"İnekler bataklıkta (sazlıkta) otluyordu.","e2":"Salt marsh.","e2t":"Tuz bataklığı."},{"w":"marshal","tr":"(askeri) mareşal / sıralamak / düzenlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A high","dt":"ranking officer; or to arrange in order","e1":"Üst rütbeli subay; veya sıraya dizmek/düzenlemek","e1t":"Air Chief Marshal.","e2":"Hava Kuvvetleri Komutanı (Mareşal).","e2t":"To marshal facts for an argument."},{"w":"martial","tr":"askeri / savaşla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to war or the armed forces","dt":"Savaş veya silahlı kuvvetler ile ilgili","e1":"Martial arts (like karate).","e1t":"Savaş sanatları.","e2":"Martial law.","e2t":"Sıkıyönetim."},{"w":"martyr","tr":"şehit / çilekeş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who suffers or dies for a belief","dt":"Bir inanç uğruna acı çeken veya ölen kişi","e1":"He died a martyr.","e1t":"Şehit olarak öldü.","e2":"To be a martyr to your work.","e2t":"İşinin kurbanı (çilekeşi) olmak."},{"w":"marvel","tr":"hayret etmek / mucize / harika","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be surprised or to admire; or a wonderful thing","dt":"Şaşırmak veya hayran kalmak; veya harika şey","e1":"I marvel at his energy.","e1t":"Onun enerjisine hayret ediyorum.","e2":"The engineering marvels of the ancient world.","e2t":"Antik dünyanın mühendislik harikaları."},{"w":"masculine","tr":"erkeksi / eril","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having qualities typical of men; or a gender","dt":"Erkeklere has özelliklere sahip olan; veya bir cinsiyet","e1":"Masculine voice.","e1t":"Erkeksi ses.","e2":"In French, many nouns are masculine.","e2t":"Fransızcada birçok isim erildir."},{"w":"massive","tr":"devasa / çok büyük / kütlesel","te":"Adjective","tt":"Sıfat","de":"Very large and heavy","dt":"Çok büyük ve ağır","e1":"A massive building.","e1t":"Devasa bir bina.","e2":"A massive heart attack.","e2t":"Çok şiddetli bir kalp krizi."},{"w":"mate","tr":"eş / arkadaş / çiftleşmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A partner or a friend; or (of animals) to have sex","dt":"Partner veya arkadaş; veya (hayvanlar için) çiftleşmek","e1":"Soul mate.","e1t":"Ruh eşi.","e2":"Running mate (politics).","e2t":"Başkan yardımcısı adayı."},{"w":"materialize / materialise","tr":"gerçekleşmek / somutlaşmak / ortaya çıkmak","te":"Verb","tt":"Fiil","de":"To become real or happen; or to appear suddenly","dt":"Gerçek olmak veya gerçekleşmek; veya aniden belirmek","e1":"Our plans failed to materialize.","e1t":"Planlarımız gerçekleşmedi.","e2":"The ghost materialized from the shadows.","e2t":"Hayalet gölgelerin arasından belirdi."},{"w":"maternal","tr":"anneye özgü / anne tarafı","te":"Adjective","tt":"Sıfat","de":"Relating to a mother; or inherited from the mother's side","dt":"Anne ile ilgili veya anne tarafından gelen","e1":"Maternal instincts.","e1t":"Anneye özgü içgüdüler.","e2":"My maternal grandfather.","e2t":"Anne tarafındaki dedem."},{"w":"mathematical","tr":"matematiksel","te":"Adjective","tt":"Sıfat","de":"Relating to mathematics","dt":"Matematik ile ilgili","e1":"A mathematical formula.","e1t":"Matematiksel bir formül.","e2":"Mathematical precision.","e2t":"Matematiksel kesinlik."},{"w":"matrix","tr":"matris / ana kalıp / ortam","te":"Noun","tt":"İsim","de":"A set of numbers arranged in rows; or the environment in which something develops","dt":"Satırlar halinde düzenlenmiş sayılar seti; veya bir şeyin geliştiği ortam","e1":"A 3x3 matrix.","e1t":"3x3 bir matris.","e2":"The cultural matrix of a society.","e2t":"Bir toplumun kültürel ana yapısı (ortamı)."},{"w":"mattress","tr":"yatak şiltesi / minder","te":"Noun","tt":"İsim","de":"The soft part of a bed that you lie on","dt":"Yatağın üzerine yatılan yumuşak kısmı","e1":"A firm mattress is good for your back.","e1t":"Sert bir yatak sırtınız için iyidir.","e2":"Spring mattress.","e2t":"Yaylı yatak."},{"w":"meadow","tr":"çayır / mera","te":"Noun","tt":"İsim","de":"A field with grass and flowers","dt":"Çimen ve çiçeklerle dolu alan","e1":"Cows were grazing in the meadow.","e1t":"İnekler çayırda otluyordu.","e2":"A mountain meadow.","e2t":"Dağ çayırı."},{"w":"mean","tr":"anlamına gelmek / cimri / kaba / ortalama","te":"Verb/Adj/Noun","tt":"To express a meaning; or not generous; or middle value","de":"Bir anlam ifade etmek; veya cimri; veya ortalama değer","dt":"What does this word mean?","e1":"Bu kelime ne anlama geliyor?","e1t":"He is very mean with his money.","e2":"Parası konusunda çok cimridir.","e2t":""},{"w":"meander","tr":"kıvrılarak akmak / dolanmak / başıboş gezmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To follow a route that is not straight; or to wander","dt":"Düz olmayan bir rota izlemek; veya dolanmak","e1":"The river meanders through the valley.","e1t":"Nehir vadide kıvrılarak akar.","e2":"We spent the afternoon meandering around the old town.","e2t":"Öğleden sonrayı eski şehirde dolanarak geçirdik."},{"w":"measurable","tr":"ölçülebilir / somut","te":"Adjective","tt":"Sıfat","de":"Able to be measured; or noticeable","dt":"Ölçülebilen; veya fark edilebilir","e1":"Measurable results.","e1t":"Ölçülebilir sonuçlar.","e2":"A measurable improvement.","e2t":"Somut (fark edilebilir) bir iyileşme."},{"w":"mediate","tr":"arabuluculuk yapmak / uzlaştırmak","te":"Verb","tt":"Fiil","de":"To help solve a disagreement between two groups","dt":"İki grup arasındaki bir anlaşmazlığı çözmeye yardımcı olmak","e1":"The UN tried to mediate between the two countries.","e1t":"BM iki ülke arasında arabuluculuk yapmaya çalıştı.","e2":"To mediate a dispute.","e2t":"Bir tartışmada uzlaştırma sağlamak."},{"w":"mediocre","tr":"vasat / orta karar / pek de iyi olmayan","te":"Adjective","tt":"Sıfat","de":"Not very good; of only average quality","dt":"Çok iyi olmayan; sadece ortalama kalitede","e1":"A mediocre performance.","e1t":"Vasat bir performans.","e2":"The film was mediocre at best.","e2t":"Film en iyi ihtimalle orta karardı."},{"w":"meditate","tr":"meditasyon yapmak / derin düşünmek","te":"Verb","tt":"Fiil","de":"To think calmly for a long time; or for religious reasons","dt":"Uzun süre sakince düşünmek; veya dini nedenlerle meditasyon yapmak","e1":"He meditates for 20 minutes every morning.","e1t":"Her sabah 20 dakika meditasyon yapar.","e2":"To meditate on a problem.","e2t":"Bir problem üzerinde derinlemesine düşünmek."},{"w":"meek","tr":"uysal / alçakgönüllü / mülayim","te":"Adjective","tt":"Sıfat","de":"Quiet, gentle, and willing to obey others","dt":"Sessiz, nazik ve başkalarına uymaya hazır","e1":"She gave a meek apology.","e1t":"Uysalca bir özür diledi.","e2":"He is as meek as a lamb.","e2t":"Kuzu gibi uysaldır."},{"w":"melancholy","tr":"melankoli / hüzün / karamsarlık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A feeling of sadness, often without a clear cause","dt":"Genellikle net bir nedeni olmayan hüzün hissi","e1":"A deep sense of melancholy.","e1t":"Derin bir melankoli hissi.","e2":"Melancholy music.","e2t":"Hüzünlü (melankolik) müzik."},{"w":"mellow","tr":"yumuşak / olgun / hoş (ses/ışık)","te":"Adjective/Verb","tt":"Smooth and soft; or relaxed and pleasant","de":"Pürüzsüz ve yumuşak; veya rahat ve hoş","dt":"A mellow wine.","e1":"Yumuşak (içimli) bir şarap.","e1t":"He has become more mellow as he has grown older.","e2":"Yaşlandıkça daha olgun (mülayim) biri oldu.","e2t":""},{"w":"melodramatic","tr":"melodramatik / abartılı duygusal","te":"Adjective","tt":"Sıfat","de":"Showing much stronger emotions than are necessary","dt":"Gerektiğinden çok daha güçlü duygular gösteren","e1":"Don't be so melodramatic!","e1t":"Bu kadar melodramatik (abartılı) olma!","e2":"A melodramatic scene.","e2t":"Abartılı duygusal bir sahne."},{"w":"membrane","tr":"zar","te":"Noun","tt":"İsim","de":"A thin layer of skin or tissue","dt":"İnce deri veya doku tabakası","e1":"Cell membrane.","e1t":"Hücre zarı.","e2":"Waterproof membrane.","e2t":"Su geçirmez zar (tabaka)."},{"w":"memo","tr":"not / muhtıra / iç yazışma","te":"Noun","tt":"İsim","de":"A short written message from one person to another in an office","dt":"Bir ofis içinde birinden diğerine gönderilen kısa yazılı mesaj","e1":"I sent a memo to all staff members.","e1t":"Tüm personele bir not (memo) gönderdim.","e2":"Internal memo.","e2t":"Dahili not."},{"w":"memorable","tr":"unutulmaz / hatırda kalan","te":"Adjective","tt":"Sıfat","de":"Worth remembering or easy to remember","dt":"Hatırlanmaya değer veya hatırlaması kolay","e1":"A memorable experience.","e1t":"Unutulmaz bir deneyim.","e2":"A memorable performance.","e2t":"Hatırda kalan bir performans."},{"w":"memorial","tr":"anıt / abide / hatıra","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An object built to remind people of a person or event","dt":"Bir kişiyi veya olayı hatırlatmak için yapılan nesne","e1":"A war memorial.","e1t":"Savaş anıtı.","e2":"A memorial service.","e2t":"Anma töreni."},{"w":"menace","tr":"tehdit / tehlike / korku salmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person or thing that is likely to cause harm","dt":"Zarar vermesi muhtemel olan kişi veya şey","e1":"Air pollution is a menace to health.","e1t":"Hava kirliliği sağlık için bir tehdittir.","e2":"He spoke with a hint of menace in his voice.","e2t":"Sesinde bir tehdit tonuyla konuştu."},{"w":"merchandise","tr":"ticari eşya / mal / tanıtım ürünü","te":"Noun/Verb","tt":"İsim/Fiil","de":"Goods that are bought and sold","dt":"Alınıp satılan mallar","e1":"Official movie merchandise.","e1t":"Resmi film tanıtım ürünleri.","e2":"This store sells high","e2t":"quality merchandise."},{"w":"merchant","tr":"tüccar / tacir","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person whose job is to buy and sell goods in large amounts","dt":"İşi büyük miktarlarda mal alıp satmak olan kişi","e1":"A wine merchant.","e1t":"Şarap tüccarı.","e2":"Merchant navy.","e2t":"Ticaret filosu."},{"w":"merciful","tr":"merhametli / insaflı","te":"Adjective","tt":"Sıfat","de":"Someone who shows kindness and forgiveness","dt":"Nezaket ve bağışlayıcılık gösteren","e1":"A merciful judge.","e1t":"Merhametli bir yargıç.","e2":"Be merciful to the poor.","e2t":"Fakirlere karşı merhametli ol."},{"w":"mercury","tr":"cıva","te":"Noun","tt":"İsim","de":"A heavy, silver","dt":"white metal that is liquid at room temperature","e1":"Oda sıcaklığında sıvı olan ağır, gümüş","e1t":"beyaz metal","e2":"The mercury is rising (the temperature is getting hotter).","e2t":"Cıva yükseliyor (hava ısınıyor)."},{"w":"merger","tr":"birleşme (şirket vb.) / fúzyon","te":"Noun","tt":"İsim","de":"The act of joining two or more organizations into one","dt":"İki veya daha fazla kuruluşun birleşerek tek bir yapı olması","e1":"A merger between two giant banks.","e1t":"İki dev banka arasındaki birleşme.","e2":"To propose a merger.","e2t":"Birleşme teklif etmek."},{"w":"meridian","tr":"meridyen / boylam çizgisi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An imaginary line from the North Pole to the South Pole","dt":"Kuzey Kutbu'ndan Güney Kutbu'na uzanan hayali çizgi","e1":"The Prime Meridian.","e1t":"Başlangıç meridyeni.","e2":"Meridian lines.","e2t":"Meridyen çizgileri."},{"w":"metallic","tr":"metalik / madeni","te":"Adjective","tt":"Sıfat","de":"Made of metal or looking like metal","dt":"Metalden yapılmış veya metale benzeyen","e1":"A metallic sound.","e1t":"Metalik (madeni) bir ses.","e2":"Metallic paint.","e2t":"Metalik boya."},{"w":"meteor","tr":"göktaşı / meteor","te":"Noun","tt":"İsim","de":"A rock from outer space that burns as it enters the Earth's atmosphere","dt":"Dünya atmosferine girerken yanan uzay taşı","e1":"A meteor shower.","e1t":"Meteor yağmuru.","e2":"To track a meteor.","e2t":"Bir meteoru takip etmek."},{"w":"methodical","tr":"yöntemli / düzenli / sistemli","te":"Adjective","tt":"Sıfat","de":"Doing things in a very ordered and careful way","dt":"İşleri çok düzenli ve dikkatli bir şekilde yapan","e1":"A methodical approach to work.","e1t":"İşe yöntemli (sistemli) bir yaklaşım.","e2":"He is very methodical in his research.","e2t":"Araştırmasında çok düzenlidir."},{"w":"meticulous","tr":"titiz / çok dikkatli / özenli","te":"Adjective","tt":"Sıfat","de":"Giving great attention to every detail","dt":"Her detaya büyük önem veren","e1":"He is meticulous about his appearance.","e1t":"Görünüşü konusunda çok titizdir.","e2":"Meticulous planning.","e2t":"Titiz (özenli) planlama."},{"w":"microscope","tr":"mikroskop","te":"Noun","tt":"İsim","de":"A device used for looking at very small objects","dt":"Çok küçük nesnelere bakmak için kullanılan cihaz","e1":"To look at bacteria through a microscope.","e1t":"Bakterilere mikroskopla bakmak.","e2":"Electron microscope.","e2t":"Elektron mikroskobu."},{"w":"mighty","tr":"güçlü / devasa / çok","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Very large, powerful, or important","dt":"Çok büyük, güçlü veya önemli","e1":"The mighty Amazon river.","e1t":"Güçlü (devasa) Amazon nehri.","e2":"A mighty blow.","e2t":"Şiddetli bir darbe."},{"w":"migrant","tr":"göçmen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who moves from one place to another to find work","dt":"İş bulmak için bir yerden başka bir yere giden kişi","e1":"Economic migrants.","e1t":"Ekonomik göçmenler.","e2":"Migrant workers.","e2t":"Mevsimlik (göçmen) işçiler."},{"w":"militant","tr":"militan / saldırgan / kavgacı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Willing to use strong or violent methods to achieve something","dt":"Bir şeyi başarmak için sert veya şiddetli yöntemler kullanmaya hazır","e1":"Militant groups.","e1t":"Militan gruplar.","e2":"A militant environmentalist.","e2t":"Kavgacı (sert yöntemli) bir çevreci."},{"w":"militia","tr":"milis / halk gücü","te":"Noun","tt":"İsim","de":"A group of ordinary people trained as soldiers","dt":"Asker olarak eğitilmiş sıradan insanlar grubu","e1":"The town was defended by a local militia.","e1t":"Kasaba yerel bir milis gücü tarafından savunuldu.","e2":"To join the militia.","e2t":"Milislere katılmak."},{"w":"mill","tr":"değirmen / fabrika / öğütmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A factory; or a machine for crushing grain","dt":"Fabrika; veya tahıl ezme makinesi","e1":"A wind mill.","e1t":"Yel değirmeni.","e2":"To mill flour.","e2t":"Un öğütmek."},{"w":"mimic","tr":"taklit etmek / taklitçi","te":"Verb/Noun/Adj","tt":"To copy the way someone speaks or behaves","de":"Birinin konuşma veya davranış şeklini kopyalamak","dt":"He can mimic the voices of many famous actors.","e1":"Birçok ünlü aktörün sesini taklit edebilir.","e1t":"A clever mimic.","e2":"Zeki bir taklitçi.","e2t":""},{"w":"mince","tr":"kıymak / kıyma / (kelimeleri) esirgememek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cut food into very small pieces","dt":"Yiyeceği çok küçük parçalara kesmek","e1":"Minced meat.","e1t":"Kıyma.","e2":"To mince onions.","e2t":"Soğanları ince ince kıymak."},{"w":"mineral","tr":"mineral / maden","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A natural substance like coal or gold; or for health","dt":"Kömür veya altın gibi doğal madde; veya sağlık için","e1":"Mineral water.","e1t":"Maden suyu (mineralli su).","e2":"Rich in vitamins and minerals.","e2t":"Vitamin ve mineraller bakımından zengin."},{"w":"mingle","tr":"karışmak (topluluğa) / kaynaşmak / birleşmek","te":"Verb","tt":"Fiil","de":"To mix or combine; or to move around in a crowd","dt":"Karışmak veya birleşmek; veya bir kalabalık içinde dolaşmak","e1":"The smells of coffee and fresh bread mingled.","e1t":"Kahve ve taze ekmek kokuları birbirine karıştı.","e2":"To mingle with the guests at the party.","e2t":"Partideki konuklarla kaynaşmak (aralarına karışmak)."},{"w":"miniature","tr":"minyatür / çok küçük","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"A very small version of something much larger","dt":"Çok daha büyük bir şeyin çok küçük versiyonu","e1":"A miniature camera.","e1t":"Minyatür kamera.","e2":"Collecting miniature cars.","e2t":"Minyatür araba koleksiyonu yapmak."},{"w":"minimal","tr":"asgari / çok az / en az","te":"Adjective","tt":"Sıfat","de":"Very small in amount or degree","dt":"Miktar veya derece olarak çok az","e1":"Minimal damage.","e1t":"Asgari (çok az) hasar.","e2":"The cost of the project was minimal.","e2t":"Projenin maliyeti asgari düzeydeydi."},{"w":"minimize / minimise","tr":"en az indirmek / küçültmek / hafife almak","te":"Verb","tt":"Fiil","de":"To reduce something to the smallest possible level","dt":"Bir şeyi mümkün olan en küçük seviyeye indirmek","e1":"We must minimize the risks.","e1t":"Riskleri en aza indirmeliyiz.","e2":"To minimize a window on the screen.","e2t":"Ekrandaki bir pencereyi küçültmek."},{"w":"mint","tr":"nane / darphane / gıcır gıcır","te":"Noun/Verb/Adj","tt":"A plant; or where money is made; or perfect condition","de":"Bitki; veya paranın basıldığı yer; veya kusursuz durum","dt":"Mint tea.","e1":"Nane çayı.","e1t":"The coin was produced by the national mint.","e2":"Madeni para darphane tarafından üretildi.","e2t":""},{"w":"minus","tr":"eksi / eksiklik","te":"Prep/Adj/Noun","tt":"Less; or a disadvantage","de":"Daha az; veya dezavantaj","dt":"Five minus two equals three.","e1":"Beş eksi iki eşittir üç.","e1t":"Minus ten degrees.","e2":"Eksi on derece.","e2t":""},{"w":"mirth","tr":"neşe / kahkaha / eğlence","te":"Noun","tt":"İsim","de":"Laughter and happiness","dt":"Kahkaha ve mutluluk","e1":"His stories caused much mirth.","e1t":"Hikayeleri büyük neşeye yol açtı.","e2":"Full of mirth.","e2t":"Neşe dolu."},{"w":"mischief","tr":"yaramazlık / haşarılık / zarar","te":"Noun","tt":"İsim","de":"Behavior that is slightly bad but not intended to cause harm","dt":"Zarar verme amacı gütmeyen hafif yaramazlık","e1":"The children are getting into mischief.","e1t":"Çocuklar yaramazlık yapıyor.","e2":"To cause mischief.","e2t":"Karışıklık (yaramazlık) çıkarmak."},{"w":"miser","tr":"cimri / pinti","te":"Noun","tt":"İsim","de":"A person who loves money and hates spending it","dt":"Parayı seven ve harcamaktan nefret eden kişi","e1":"The old miser lived alone in a small room.","e1t":"Yaşlı cimri küçük bir odada yalnız yaşıyordu.","e2":"Miserly behavior.","e2t":"Pinti davranış."},{"w":"misery","tr":"sefalet / perişanlık / büyük acı","te":"Noun","tt":"İsim","de":"Great suffering or unhappiness","dt":"Büyük acı veya mutsuzluk","e1":"Thousands of people are living in misery.","e1t":"Binlerce insan sefalet içinde yaşıyor.","e2":"To end someone's misery.","e2t":"Birinin acısına (perişanlığına) son vermek."},{"w":"misleading","tr":"yanıltıcı / aldatıcı","te":"Adjective","tt":"Sıfat","de":"Causing someone to believe something that is not true","dt":"Birinin doğru olmayan bir şeye inanmasına neden olan","e1":"Misleading advertisements.","e1t":"Yanıltıcı reklamlar.","e2":"The information was highly misleading.","e2t":"Bilgi son derece yanıltıcıydı."},{"w":"misplace","tr":"yanlış yere koymak / kaybetmek","te":"Verb","tt":"Fiil","de":"To put something in the wrong place and lose it","dt":"Bir şeyi yanlış yere koyup kaybetmek","e1":"I've misplaced my keys again.","e1t":"Anahtarlarımı yine yanlış yere koydum (bulamıyorum).","e2":"Misplaced confidence.","e2t":"Yersiz (yanlış yere duyulan) güven."},{"w":"missile","tr":"füze / mermi","te":"Noun","tt":"İsim","de":"An explosive weapon that can fly through the air","dt":"Havada uçabilen patlayıcı silah","e1":"A long","e1t":"range missile.","e2":"Uzun menzilli füze.","e2t":"Guided missile."},{"w":"mistrust","tr":"güvensizlik / güvenmemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling that you cannot trust someone","dt":"Birine güvenememe hissi","e1":"A deep mistrust of politicians.","e1t":"Politikacılara karşı derin bir güvensizlik.","e2":"To mistrust someone's motives.","e2t":"Birinin niyetinden şüphe etmek (güvenmemek)."},{"w":"mitigate","tr":"hafifletmek / azaltmak / dindirmek","te":"Verb","tt":"Fiil","de":"To make something less harmful or serious","dt":"Bir şeyi daha az zararlı veya ciddi hale getirmek","e1":"Measures to mitigate climate change.","e1t":"İklim değişikliğini hafifletme önlemleri.","e2":"To mitigate the effects of poverty.","e2t":"Yoksulluğun etkilerini azaltmak."},{"w":"mix","tr":"karıştırmak / karışım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To combine different substances together","dt":"Farklı maddeleri bir araya getirmek","e1":"Mix the flour and sugar together.","e1t":"Unu ve şekeri birlikte karıştırın.","e2":"A mix of different cultures.","e2t":"Farklı kültürlerin bir karışımı."},{"w":"moan","tr":"inlemek / sızlanmak / uğuldamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a low sound of pain; or to complain","dt":"Acıyla alçak ses çıkarmak; veya şikayet etmek","e1":"He moaned with pain.","e1t":"Acıyla inledi.","e2":"Stop moaning about the weather!","e2t":"Hava hakkında sızlanmayı bırak!"},{"w":"mobilize / mobilise","tr":"harekete geçirmek / seferber etmek","te":"Verb","tt":"Fiil","de":"To organize for a particular purpose","dt":"Belirli bir amaç için organize etmek (toplamak)","e1":"The government is trying to mobilize public support.","e1t":"Hükümet kamu desteğini harekete geçirmeye çalışıyor.","e2":"To mobilize the army.","e2t":"Orduyu seferber etmek."},{"w":"modest","tr":"mütevazı / alçakgönüllü / gösterişsiz","te":"Adjective","tt":"Sıfat","de":"Not large in amount; or not talking about your success","dt":"Miktar olarak büyük olmayan; veya başarılarından söz etmeyen","e1":"He is very modest about his achievements.","e1t":"Başarıları konusunda çok mütevazıdır.","e2":"A modest house.","e2t":"Mütevazı (gösterişsiz) bir ev."},{"w":"mold / mould","tr":"kalıp / küf / şekil vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A container to give shape; or a fungus on old food","dt":"Şekil veren kap; veya bayat gıdadaki mantar","e1":"Pour the mixture into the mold.","e1t":"Karışımı kalıba dökün.","e2":"There is mold on the bread.","e2t":"Ekmeğin üzerinde küf var."},{"w":"momentary","tr":"anlık / geçici","te":"Adjective","tt":"Sıfat","de":"Lasting for only a very short time","dt":"Sadece çok kısa bir süre devam eden","e1":"A momentary lapse of concentration.","e1t":"Anlık bir konsantrasyon bozukluğu.","e2":"Momentary confusion.","e2t":"Geçici kafa karışıklığı."},{"w":"momentum","tr":"hız / ivme / hareket gücü","te":"Noun","tt":"İsim","de":"The force that keeps an object moving","dt":"Bir nesnenin hareketini sürdüren güç","e1":"The campaign is gaining momentum.","e1t":"Kampanya hız (ivme) kazanıyor.","e2":"To lose momentum.","e2t":"Hızını kaybetmek."},{"w":"monarch","tr":"hükümdar / monark","te":"Noun","tt":"İsim","de":"A king or queen who rules a country","dt":"Bir ülkeyi yöneten kral veya kraliçe","e1":"The reigning monarch.","e1t":"Tahttaki hükümdar.","e2":"Britain’s constitutional monarch.","e2t":"Britanya'nın anayasal hükümdarı."},{"w":"monastery","tr":"manastır","te":"Noun","tt":"İsim","de":"A building where monks live and work together","dt":"Keşişlerin birlikte yaşadığı ve çalıştığı bina","e1":"A Buddhist monastery.","e1t":"Budist manastırı.","e2":"To live in a monastery.","e2t":"Bir manastırda yaşamak."},{"w":"monetary","tr":"parasal / mali","te":"Adjective","tt":"Sıfat","de":"Relating to money or currency","dt":"Para veya para birimi ile ilgili","e1":"Monetary policy.","e1t":"Para politikası.","e2":"International Monetary Fund (IMF).","e2t":"Uluslararası Para Fonu."},{"w":"monopoly","tr":"tekel / monopol","te":"Noun","tt":"İsim","de":"Complete control of a product or service by one company","dt":"Bir ürün veya hizmetin tek bir şirketçe kontrol edilmesi","e1":"The company has a monopoly on the market.","e1t":"Şirketin piyasada tekeli var.","e2":"To break a monopoly.","e2t":"Bir tekeli kırmak."},{"w":"monotonous","tr":"tekdüze / monoton / sıkıcı","te":"Adjective","tt":"Sıfat","de":"Boring because it never changes","dt":"Hiç değişmediği için sıkıcı olan","e1":"A monotonous voice.","e1t":"Tekdüze bir ses.","e2":"His work is very monotonous.","e2t":"İşi çok tekdüzedir."},{"w":"morality","tr":"ahlak / ahlaklılık","te":"Noun","tt":"İsim","de":"Principles concerning the distinction between right and wrong","dt":"Doğru ve yanlış arasındaki ayrımla ilgili ilkeler","e1":"Public morality.","e1t":"Kamu ahlakı.","e2":"A question of morality.","e2t":"Ahlak meselesi."},{"w":"morbid","tr":"hastalıklı / ürkütücü / moral bozucu","te":"Adjective","tt":"Sıfat","de":"Having an unhealthy interest in death or unpleasant things","dt":"Ölüme veya nahoş şeylere hastalıklı bir ilgi duyma","e1":"A morbid fascination with crime.","e1t":"Suça karşı hastalıklı bir hayranlık.","e2":"Morbid thoughts.","e2t":"Karamsar (hastalıklı) düşünceler."},{"w":"mortal","tr":"ölümlü / öldürücü / fani","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Subject to death; or causing death","dt":"Ölüme tabi olan; veya ölüme neden olan","e1":"All men are mortal.","e1t":"Tüm insanlar ölümlüdür.","e2":"A mortal wound.","e2t":"Öldürücü bir yara."},{"w":"mortality","tr":"ölümlülük / ölüm oranı","te":"Noun","tt":"İsim","de":"The state of being mortal; or the number of deaths","dt":"Ölümlü olma durumu; veya ölüm sayısı","e1":"To face one's own mortality.","e1t":"Kendi ölümlülüğüyle yüzleşmek.","e2":"Infant mortality rate.","e2t":"Bebek ölüm oranı."},{"w":"motto","tr":"slogan / düstur","te":"Noun","tt":"İsim","de":"A short sentence or phrase that expresses a belief","dt":"Bir inancı ifade eden kısa cümle veya ifade","e1":"\"Quality first\" is the company's motto.","e1t":"\"Önce kalite\" şirketin sloganıdır.","e2":"Family motto.","e2t":"Aile düsturu."},{"w":"mound","tr":"tümsek / yığın / tepecik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large pile of something; or a small hill","dt":"Bir şeyin büyük yığını; veya küçük tepe","e1":"A mound of rubbish.","e1t":"Bir çöp yığını.","e2":"Ancient burial mounds.","e2t":"Antik mezar höyükleri (tümsekleri)."},{"w":"muddy","tr":"çamurlu / bulanık","te":"Adjective/Verb","tt":"Covered in mud; or not clear","de":"Çamurla kaplı; veya net olmayan","dt":"Muddy boots.","e1":"Çamurlu botlar.","e1t":"A muddy river.","e2":"Bulanık (çamurlu) bir nehir.","e2t":""},{"w":"muffler","tr":"susturucu / atkı (kalın)","te":"Noun","tt":"İsim","de":"A part of a car that reduces noise; or a thick scarf","dt":"Arabanın gürültüsünü azaltan parça; veya kalın atkı","e1":"The car needs a new muffler.","e1t":"Arabanın yeni bir susturucuya ihtiyacı var.","e2":"He wore a heavy wool muffler.","e2t":"Kalın yün bir atkı takıyordu."},{"w":"multilateral","tr":"çok taraflı","te":"Adjective","tt":"Sıfat","de":"Involving more than two groups or countries","dt":"İkiden fazla grup veya ülkeyi kapsayan","e1":"Multilateral trade agreements.","e1t":"Çok taraflı ticaret anlaşmaları.","e2":"Multilateral cooperation.","e2t":"Çok taraflı işbirliği."},{"w":"multiple","tr":"çoklu / çeşitli / kat (matematik)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Very many; or a number that can be divided exactly","dt":"Çok sayıda; veya tam bölünebilen sayı","e1":"He suffered multiple injuries.","e1t":"Çok sayıda yaralanma yaşadı.","e2":"12 is a multiple of 3.","e2t":"12, 3'ün bir katıdır."},{"w":"multiplication","tr":"çarpma / çoğalma","te":"Noun","tt":"İsim","de":"The process of adding a number to itself many times","dt":"Bir sayının kendisiyle birçok kez toplanması işlemi","e1":"Multiplication table.","e1t":"Çarpım tablosu.","e2":"The rapid multiplication of bacteria.","e2t":"Bakterilerin hızla çoğalması."},{"w":"mumble","tr":"mırıldanmak / ağız içinde konuşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak quietly and in a way that is not clear","dt":"Sessizce ve net olmayan bir şekilde konuşmak","e1":"Stop mumbling and speak up!","e1t":"Mırıldanmayı bırak ve yüksek sesle konuş!","e2":"He mumbled an apology.","e2t":"Bir özür mırıldandı."},{"w":"mundane","tr":"sıradan / dünyevi / heyecansız","te":"Adjective","tt":"Sıfat","de":"Ordinary and not interesting","dt":"Sıradan ve ilginç olmayan","e1":"Mundane chores like washing dishes.","e1t":"Bulaşık yıkamak gibi sıradan işler.","e2":"Mundane world.","e2t":"Dünyevi alem."},{"w":"munition","tr":"mühimmat / cephane","te":"Noun/Verb","tt":"İsim/Fiil","de":"Military weapons such as guns and bombs","dt":"Silah ve bomba gibi askeri malzemeler","e1":"A munition factory.","e1t":"Mühimmat fabrikası.","e2":"To run out of munitions.","e2t":"Cephanesi bitmek."},{"w":"murmur","tr":"mırıldanmak / uğultu / hışırtı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak very quietly; or a soft continuous sound","dt":"Çok sessiz konuşmak; veya yumuşak sürekli ses","e1":"She murmured something in his ear.","e1t":"Kulağına bir şeyler mırıldandı.","e2":"The murmur of the waves.","e2t":"Dalgaların hışırtısı."},{"w":"muse","tr":"ilham perisi / derin düşünmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"a person who provides inspiration; or to think deeply","dt":"İlham kaynağı olan kişi; veya derin düşünmek","e1":"She was the artist's muse.","e1t":"Sanatçının ilham perisiydi.","e2":"He mused on the meaning of life.","e2t":"Hayatın anlamı üzerine derin derin düşündü."},{"w":"musical","tr":"müzikal / müziğe yetenekli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to music; or good at music","dt":"Müzik ile ilgili; veya müziğe yeteneği olan","e1":"He is very musical.","e1t":"Müziğe çok yeteneklidir.","e2":"A musical instrument.","e2t":"Müzik aleti."},{"w":"muster","tr":"toplamak (cesaret vb.) / yoklama yapmak / içtimaya çıkmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce as much of a feeling as you can; or to gather soldiers","dt":"Bir duyguyu (olabildiğince) toplamak; veya askerleri toplamak","e1":"He finally mustered the courage to ask her out.","e1t":"Sonunda ona çıkma teklifi etme cesaretini topladı.","e2":"To muster the troops.","e2t":"Birlikleri toplamak (içtima yapmak)."},{"w":"musty","tr":"küf kokulu / bayat / köhne","te":"Adjective","tt":"Sıfat","de":"Smelling old and slightly wet","dt":"Eski ve hafif ıslak kokan","e1":"Musty old books.","e1t":"Küf kokulu eski kitaplar.","e2":"The room smelled musty.","e2t":"Oda küf kokuyordu."},{"w":"mute","tr":"sessiz / dilsiz / sesini kısmak","te":"Adjective/Noun/Verb","tt":"Unable to speak; or to silence a sound","de":"Konuşamayan; veya bir sesi susturmak","dt":"He has been mute since birth.","e1":"Doğuştan dilsizdir.","e1t":"Press the mute button.","e2":"Sessiz (mute) düğmesine basın.","e2t":""},{"w":"mutter","tr":"söylenmek / mırıldanmak (şikayet ederek)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak quietly and in a low voice, often complaining","dt":"Genellikle şikayet ederek alçak sesle konuşmak","e1":"He muttered something under his breath.","e1t":"Kendi kendine (dişlerinin arasından) bir şeyler söylendi.","e2":"\"It’s not fair,\" she muttered.","e2t":"\"Adil değil,\" diye söylendi."},{"w":"muzzle","tr":"namlu / ağızlık / susturmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The end of a gun; or a cover for an animal's mouth","dt":"Silahın ucu; veya hayvanın ağzına takılan kapak","e1":"The muzzle of a rifle.","e1t":"Tüfeğin namlusu.","e2":"The dog had to wear a muzzle.","e2t":"Köpeğe ağızlık takılması gerekiyordu."},{"w":"mythology","tr":"mitoloji","te":"Noun","tt":"İsim","de":"Ancient stories about gods and heroes","dt":"Tanrılar ve kahramanlar hakkında eski hikayeler","e1":"Greek mythology.","e1t":"Yunan mitolojisi.","e2":"A scholar of mythology.","e2t":"Mitoloji uzmanı."},{"w":"naive / naïve","tr":"saf / toy / deneyimsiz","te":"Adjective","tt":"Sıfat","de":"Lacking experience and believing people too easily","dt":"Deneyimi olmayan ve insanlara kolayca inanan","e1":"It was naive of you to believe him.","e1t":"Ona inanman saflıktı.","e2":"A naive young man.","e2t":"Toy (saf) bir genç adam."},{"w":"narrate","tr":"anlatmak / seslendirmek","te":"Verb","tt":"Fiil","de":"To tell a story or describe events","dt":"Bir hikaye anlatmak veya olayları betimlemek","e1":"The documentary is narrated by a famous actor.","e1t":"Belgeseli ünlü bir aktör seslendiriyor (anlatıyor).","e2":"To narrate a plot.","e2t":"Bir olay örgüsünü anlatmak."},{"w":"narrative","tr":"anlatı / öyküleme","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A story or a description of events","dt":"Bir hikaye veya olayların betimlenmesi","e1":"A historical narrative.","e1t":"Tarihsel bir anlatı.","e2":"Narrative techniques.","e2t":"Öyküleme teknikleri."},{"w":"nationalism","tr":"milliyetçilik","te":"Noun","tt":"İsim","de":"A strong feeling of love for your own country","dt":"Kendi ülkesine duyulan güçlü sevgi (bağlılık) hissi","e1":"Extreme nationalism can lead to conflict.","e1t":"Aşırı milliyetçilik çatışmaya yol açabilir.","e2":"Rise of nationalism.","e2t":"Milliyetçiliğin yükselişi."},{"w":"nationality","tr":"milliyet / uyruk","te":"Noun","tt":"İsim","de":"The state of belonging to a particular nation","dt":"Belirli bir ulusa ait olma durumu","e1":"What is your nationality?","e1t":"Milliyetiniz nedir?","e2":"He has dual nationality (Turkish and British).","e2t":"Çifte vatandaşlığı (uyruğu) var."},{"w":"naturalize / naturalise","tr":"vatandaşlığa kabul etmek / doğallaştırmak","te":"Verb","tt":"Fiil","de":"To make someone a legal citizen of a country","dt":"Birini bir ülkenin yasal vatandaşı yapmak","e1":"He was naturalized as a British citizen.","e1t":"İngiliz vatandaşlığına kabul edildi.","e2":"Naturalized plants.","e2t":"Doğallaşmış (uyum sağlamış) bitkiler."},{"w":"naughty","tr":"yaramaz / haylaz","te":"Adjective","tt":"Sıfat","de":"(Of a child) behaving badly","dt":"(Çocuk için) kötü davranan","e1":"A naughty boy.","e1t":"Yaramaz bir çocuk.","e2":"You've been very naughty!","e2t":"Çok yaramazlık yaptın!"},{"w":"nausea","tr":"mide bulantısı","te":"Noun","tt":"İsim","de":"The feeling that you are going to vomit","dt":"Kusacakmış gibi hissetme","e1":"A feeling of nausea.","e1t":"Mide bulantısı hissi.","e2":"Motion sickness causes nausea.","e2t":"Taşıt tutması mide bulantısına neden olur."},{"w":"naval","tr":"donanma ile ilgili / deniz kuvvetleri","te":"Adjective","tt":"Sıfat","de":"Relating to a navy or warships","dt":"Bir donanma veya savaş gemileri ile ilgili","e1":"A naval officer.","e1t":"Donanma subayı.","e2":"Naval base.","e2t":"Deniz üssü."},{"w":"nebulous","tr":"bulutsu / belirsiz / muğlak","te":"Adjective","tt":"Sıfat","de":"Not clear and having no form","dt":"Net olmayan ve şekilsiz","e1":"A nebulous concept.","e1t":"Muğlak (belirsiz) bir kavram.","e2":"Nebulous shapes in the dark.","e2t":"Karanlıkta belirsiz (bulutsu) şekiller."},{"w":"necessitate","tr":"gerektirmek / zorunlu kılmak","te":"Verb","tt":"Fiil","de":"To make something necessary","dt":"Bir şeyi gerekli kılmak","e1":"The accident necessitated a trip to the hospital.","e1t":"Kaza, hastaneye gitmeyi gerektirdi.","e2":"This decision will necessitate further changes.","e2t":"Bu karar daha fazla değişikliği zorunlu kılacak."},{"w":"needle","tr":"iğne / ibre / iğnelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin sharp metal tool for sewing; or to annoy","dt":"Dikiş dikmek için ince keskin metal alet; veya birini kızdırmak","e1":"I can't find the eye of the needle.","e1t":"İğne deliğini bulamıyorum.","e2":"Stop needling me!","e2t":"Beni iğnelemeyi (canımı sıkmayı) bırak!"},{"w":"needy","tr":"muhtaç / yoksul / ilgi bekleyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Poor and not having enough food or money","dt":"Fakir ve yeterli yiyeceği/parası olmayan","e1":"Providing aid to needy families.","e1t":"Muhtaç ailelere yardım sağlamak.","e2":"He is a bit needy (emotionally).","e2t":"Biraz ilgi bekleyen (duygusal olarak muhtaç) biri."},{"w":"negate","tr":"olumsuzlamak / çürütmek / etkisiz kılmak","te":"Verb","tt":"Fiil","de":"To cause something to have no effect or to deny","dt":"Bir şeyin etkisiz olmasına neden olmak veya inkar etmek","e1":"The increase in sales negated the loss in profits.","e1t":"Satışlardaki artış kâr kaybını telafi etti (etkisiz kıldı).","e2":"To negate a statement.","e2t":"Bir ifadeyi yalanlamak (çürütmek)."},{"w":"negligence","tr":"ihmal / savsaklama","te":"Noun","tt":"İsim","de":"Failure to take enough care in doing something","dt":"Bir şeyi yaparken yeterli özeni göstermeme","e1":"The accident was caused by negligence.","e1t":"Kaza ihmal nedeniyle meydana geldi.","e2":"Professional negligence.","e2t":"Mesleki ihmal."},{"w":"negligible","tr":"ihmal edilebilir / önemsiz","te":"Adjective","tt":"Sıfat","de":"Too slight or small to be important","dt":"Önemli olmayacak kadar hafif veya küçük","e1":"The difference in price is negligible.","e1t":"Fiyattaki fark ihmal edilebilir (çok az).","e2":"A negligible amount.","e2t":"Önemsiz bir miktar."},{"w":"neutralize / neutralise","tr":"etkisiz hale getirmek / nötrlemek","te":"Verb","tt":"Fiil","de":"To stop something from having an effect","dt":"Bir şeyin etkisini durdurmak","e1":"The cream neutralizes the acid.","e1t":"Krem asidi nötrler.","e2":"The soldiers were neutralized.","e2t":"Askerler etkisiz hale getirildi."},{"w":"nevertheless","tr":"yine de / buna rağmen / mamafih","te":"Adverb","tt":"Zarf","de":"Despite what has just been said","dt":"Söylenene rağmen","e1":"It was very cold; nevertheless, we went for a walk.","e1t":"Hava çok soğuktu; buna rağmen yürüyüşe çıktık.","e2":"He was tired, but he continued nevertheless.","e2t":"Yorgundu ama yine de devam etti."},{"w":"newcomer","tr":"yeni gelen / yeni üye","te":"Noun","tt":"İsim","de":"Someone who has recently arrived in a place","dt":"Bir yere yeni varmış (gelmiş) kişi","e1":"He is a newcomer to the city.","e1t":"O bu şehre yeni geldi.","e2":"Information for newcomers.","e2t":"Yeni gelenler için bilgiler."},{"w":"newsletter","tr":"bülten / haber bülteni","te":"Noun","tt":"İsim","de":"A printed report giving news to members of a group","dt":"Bir grup üyelerine haber veren basılı veya dijital rapor","e1":"Subscribe to our monthly newsletter.","e1t":"Aylık haber bültenimize abone olun.","e2":"School newsletter.","e2t":"Okul bülteni."},{"w":"niche","tr":"niş / özel alan / oyuk","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A specialized area or a hollow in a wall","dt":"Uzmanlaşılmış (özel) alan veya duvardaki oyuk","e1":"He found his niche in marketing.","e1t":"Pazarlamada kendi özel alanını (yerini) buldu.","e2":"Niche market.","e2t":"Niş pazar (özel kitleye hitap eden)."},{"w":"nickname","tr":"takma ad / lakap / rumuz","te":"Noun/Verb","tt":"İsim/Fiil","de":"An informal name for someone","dt":"Birisi için kullanılan resmi olmayan isim","e1":"His nickname is \"The Giant\".","e1t":"Lakabı \"Dev\"dir.","e2":"How did you get that nickname?","e2t":"Bu takma adı nasıl aldın?"},{"w":"nimble","tr":"çevik / becerikli / kıvrak","te":"Adjective","tt":"Sıfat","de":"Quick and light in movement or thought","dt":"Hareket veya düşüncede hızlı ve hafif","e1":"Nimble fingers.","e1t":"Becerikli (kıvrak) parmaklar.","e2":"He has a nimble mind.","e2t":"Kıvrak (çabuk anlayan) bir zekası var."},{"w":"nocturnal","tr":"gececil / geceye ait","te":"Adjective","tt":"Sıfat","de":"Active during the night","dt":"Gece boyunca aktif olan","e1":"Owls are nocturnal animals.","e1t":"Baykuşlar gececil hayvanlardır.","e2":"Nocturnal habits.","e2t":"Gece alışkanlıkları."},{"w":"nod","tr":"başıyla onaylamak / kafa sallamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move your head up and down as a way of saying \"yes\"","dt":"\"Evet\" demek için başı yukarı aşağı hareket ettirmek","e1":"He nodded in agreement.","e1t":"Onaylayarak başını salladı.","e2":"She gave a quick nod.","e2t":"Hızlıca başını salladı."},{"w":"nomad","tr":"göçebe","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A member of a group of people who move from place to place","dt":"Yerden yere taşınan bir gruba mensup kişi","e1":"Desert nomads.","e1t":"Çöl göçebeleri.","e2":"A digital nomad.","e2t":"Dijital göçebe (internet üzerinden her yerde çalışan)."},{"w":"nominal","tr":"ismen var olan / cüzi / önemsiz","te":"Adjective","tt":"Sıfat","de":"Existing in name only; or very small (amount)","dt":"Sadece isimde var olan; veya çok küçük (miktar)","e1":"The King is the nominal head of state.","e1t":"Kral, devletin sembolik (ismen) başkanıdır.","e2":"A nominal fee.","e2t":"Cüzi (küçük) bir miktar ücret."},{"w":"nonchalant","tr":"soğukkanlı / kayıtsız / umursamaz","te":"Adjective","tt":"Sıfat","de":"Behaving in a calm manner without worry","dt":"Endişesiz ve sakin bir şekilde davranan","e1":"He appeared nonchalant despite the danger.","e1t":"Tehlikeye rağmen umursamaz (sakin) görünüyordu.","e2":"A nonchalant attitude.","e2t":"Kayıtsız bir tavır."},{"w":"nondescript","tr":"sıradan / tarif edilemez / özelliksiz","te":"Adjective","tt":"Sıfat","de":"Having no interesting or unusual features","dt":"İlginç veya sıra dışı özelliği olmayan","e1":"He lived in a nondescript house.","e1t":"Özelliksiz (sıradan) bir evde yaşıyordu.","e2":"A nondescript person.","e2t":"Belirgin bir özelliği olmayan kişi."},{"w":"norm","tr":"norm / kural / standart","te":"Noun","tt":"İsim","de":"An accepted standard or a usual way of behaving","dt":"Kabul edilen standart veya alışılmış davranış biçimi","e1":"Social norms.","e1t":"Sosyal normlar.","e2":"Below the norm.","e2t":"Standartın altında."},{"w":"northern","tr":"kuzeyli / kuzeye ait","te":"Adjective","tt":"Sıfat","de":"In or from the north","dt":"Kuzeyde olan veya kuzeyden gelen","e1":"Northern Turkey.","e1t":"Kuzey Türkiye.","e2":"Northern lights (Aurora Borealis).","e2t":"Kuzey ışıkları."},{"w":"nostalgia","tr":"nostalji / geçmişe özlem","te":"Noun","tt":"İsim","de":"A feeling of pleasure and sadness when thinking about the past","dt":"Geçmişi düşünürken duyulan mutluluk ve hüzün karışımı his","e1":"A wave of nostalgia.","e1t":"Nostalji dalgası.","e2":"He felt nostalgia for his school days.","e2t":"Okul günlerine özlem duydu."},{"w":"notary","tr":"noter","te":"Noun","tt":"İsim","de":"An official who has the legal power to witness the signing of documents","dt":"Belgelerin imzalanmasına tanıklık etme yetkisi olan görevli","e1":"I need a notary to sign this paper.","e1t":"Bu kağıdı imzalamak için bir notere ihtiyacım var.","e2":"Public notary.","e2t":"Noter."},{"w":"notation","tr":"notasyon / simgeleme / işaretleme","te":"Noun","tt":"İsim","de":"A system of symbols used to represent something","dt":"Bir şeyi temsil etmek için kullanılan semboller sistemi","e1":"Musical notation.","e1t":"Müzik notasyonu.","e2":"Scientific notation.","e2t":"Bilimsel simgeleme."},{"w":"notch","tr":"çentik / derece / seviye","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small cut in a surface; or a level","dt":"Bir yüzeydeki küçük kesik; veya seviye","e1":"He cut a notch in the stick.","e1t":"Çubuğa bir çentik attı.","e2":"To move up a notch.","e2t":"Bir derece (seviye) yükselmek."},{"w":"noteworthy","tr":"kayda değer / dikkate değer","te":"Adjective","tt":"Sıfat","de":"Deserving attention because it is important","dt":"Önemli olduğu için ilgi hak eden","e1":"A noteworthy achievement.","e1t":"Kayda değer bir başarı.","e2":"It is noteworthy that...","e2t":"... olması dikkat çekicidir."},{"w":"notify","tr":"bildirmek / haber vermek / tebliğ etmek","te":"Verb","tt":"Fiil","de":"To tell someone officially about something","dt":"Birine bir şeyi resmi olarak söylemek","e1":"Please notify us of any changes.","e1t":"Herhangi bir değişikliği lütfen bize bildirin.","e2":"You will be notified by email.","e2t":"E"},{"w":"notorious","tr":"adı çıkmış (kötü) / dilli / meşhur","te":"Adjective","tt":"Sıfat","de":"Famous for something bad","dt":"Kötü bir şeyle ünlü olan","e1":"A notorious criminal.","e1t":"Adı çıkmış bir suçlu.","e2":"The city is notorious for its traffic jams.","e2t":"Şehir trafik sıkışıklığıyla meşhurdur (nam salmıştır)."},{"w":"novelty","tr":"yenilik / ilginçlik / ucuz süs eşyası","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The quality of being new and unusual; or a small toy","dt":"Yeni ve alışılmadık olma özelliği; veya küçük oyuncak","e1":"The novelty of the new car soon wore off.","e1t":"Yeni arabanın heyecanı (yeniliği) kısa sürede geçti.","e2":"Novelty items.","e2t":"İlginç (hediyelik) eşyalar."},{"w":"novice","tr":"acemi / yeni başlayan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is new and has little experience in a skill","dt":"Bir beceride yeni olan ve az deneyimi olan kişi","e1":"I'm a complete novice at scuba diving.","e1t":"Tüplü dalışta tamamen acemiyim.","e2":"Novice driver.","e2t":"Yeni başlayan sürücü."},{"w":"nuance","tr":"nüans / ince fark","te":"Noun","tt":"İsim","de":"A very slight difference in meaning or sound","dt":"Anlam veya seste çok hafif fark","e1":"He understood the nuances of the language.","e1t":"Dilin nüanslarını (ince detaylarını) anladı.","e2":"Without missing a nuance.","e2t":"Hiçbir nüansı kaçırmadan."},{"w":"nucleus","tr":"çekirdek / merkez / atom çekirdeği","te":"Noun","tt":"İsim","de":"The central and most important part of something","dt":"Bir şeyin merkezi ve en önemli parçası","e1":"The cell nucleus.","e1t":"Hücre çekirdeği.","e2":"The nucleus of a small team.","e2t":"Küçük bir ekibin çekirdek kadrosu."},{"w":"nullify","tr":"iptal etmek / hükümsüz kılmak / geçersiz saymak","te":"Verb","tt":"Fiil","de":"To cause something to have no value or legal power","dt":"Bir şeyin değerinin veya yasal gücünün kalmamasına neden olmak","e1":"The election results were nullified.","e1t":"Seçim sonuçları iptal edildi.","e2":"To nullify a contract.","e2t":"Bir sözleşmeyi geçersiz kılmak."},{"w":"numb","tr":"uyuşmuş / hissiz / hissizleştirmek","te":"Adjective/Verb","tt":"Unable to feel anything; or shocked","de":"Hiçbir şey hissedemeyen; veya şoke olmuş","dt":"My fingers were numb with cold.","e1":"Parmaklarım soğuktan uyuşmuştu.","e1t":"Numb with grief.","e2":"Kederden hissizleşmiş.","e2t":""},{"w":"numerical","tr":"sayısal / rakamsal","te":"Adjective","tt":"Sıfat","de":"Relating to numbers","dt":"Sayılarla ilgili","e1":"Numerical data.","e1t":"Sayısal veriler.","e2":"Arrange the files in numerical order.","e2t":"Dosyaları sayısal sıraya göre dizin."},{"w":"nun","tr":"rahibe","te":"Noun","tt":"İsim","de":"A member of a female religious group","dt":"Kadın dini grup üyesi","e1":"She decided to become a nun.","e1t":"Rahibe olmaya karar verdi.","e2":"Convent of nuns.","e2t":"Rahibeler manastırı."},{"w":"nutrient","tr":"besin / gıda / besleyici madde","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Any substance that plants or animals need in order to live","dt":"Bitkilerin veya hayvanların yaşamak için ihtiyaç duyduğu madde","e1":"Plants absorb nutrients from the soil.","e1t":"Bitkiler topraktan besinleri emer.","e2":"Essential nutrients.","e2t":"Temel besinler."},{"w":"nutrition","tr":"beslenme / besiyeri","te":"Noun","tt":"İsim","de":"The process by which living things receive food for growth","dt":"Canlıların büyüme için gıda alma süreci","e1":"Poor nutrition can lead to health problems.","e1t":"Kötü beslenme sağlık sorunlarına yol açabilir.","e2":"Information on nutrition.","e2t":"Beslenme üzerine bilgi."},{"w":"obese","tr":"obez / aşırı kilolu","te":"Adjective","tt":"Sıfat","de":"Extremely fat in a way that is dangerous for health","dt":"Sağlık için tehlikeli olacak kadar şişman","e1":"She is clinically obese.","e1t":"Klinik olarak obezdir.","e2":"To prevent children from becoming obese.","e2t":"Çocukların obez olmasını önlemek."},{"w":"obey","tr":"itaat etmek / uymak / söz dinlemek","te":"Verb","tt":"Fiil","de":"To do what you are told or follow a rule","dt":"Söyleneni yapmak veya bir kurala uymak","e1":"Soldiers must obey orders.","e1t":"Askerler emirlere itaat etmelidir.","e2":"To obey the law.","e2t":"Yasaya uymak."},{"w":"obligate","tr":"mecbur bırakmak / zorunlu kılmak","te":"Verb/Adjective","tt":"To force someone to do something as a legal or moral duty","de":"Birini yasal veya ahlaki bir görev olarak bir şeye zorlamak","dt":"I felt obligated to help him.","e1":"Ona yardım etmek zorunda (mecbur) hissettim.","e1t":"To obligate funds.","e2":"Fonları tahsis etmek (bağlamak).","e2t":""},{"w":"obligatory","tr":"zorunlu / mecburi","te":"Adjective","tt":"Sıfat","de":"If something is obligatory, you must do it","dt":"Eğer bir şey zorunluysa, onu yapmalısınız","e1":"Attendance at the meeting is obligatory.","e1t":"Toplantıya katılım zorunludur.","e2":"Obligatory education.","e2t":"Zorunlu eğitim."},{"w":"oblique","tr":"eğik / dolaylı / yan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not direct or not straight","dt":"Doğrudan veya düz olmayan","e1":"An oblique reference.","e1t":"Dolaylı bir atıf.","e2":"Oblique muscles.","e2t":"Yan karın kasları."},{"w":"obliterate","tr":"yok etmek / silip süpürmer / izini silmek","te":"Verb","tt":"Fiil","de":"To remove all signs of something; to destroy completely","dt":"Bir şeyin tüm izlerini kaldırmak; tamamen yok etmek","e1":"The building was obliterated by the bomb.","e1t":"Bina bomba ile yerle bir edildi (yok edildi).","e2":"To obliterate memories.","e2t":"Anıları silmek."},{"w":"oblivious","tr":"habersiz / farkında olmayan / unutkan","te":"Adjective","tt":"Sıfat","de":"Not noticing something or not aware of what is happening","dt":"Bir şeyi fark etmeyen veya olan bitenin farkında olmayan","e1":"He was oblivious to the danger.","e1t":"Tehlikeden habersizdi.","e2":"Absorbed in her work, she was oblivious to the noise.","e2t":"İşine daldığı için gürültünün farkında değildi."},{"w":"obscene","tr":"müstehcen / çirkin / iğrenç","te":"Adjective","tt":"Sıfat","de":"Offensive to accepted standards of behavior; or related to sex","dt":"Kabul edilen davranış standartlarına aykırı; veya cinsellikle ilgili","e1":"Obscene phone calls.","e1t":"Müstehcen telefon aramaları.","e2":"An obscene amount of money (very large).","e2t":"Akıl almaz (çok büyük) miktarda para."},{"w":"observable","tr":"gözlemlenebilir / fark edilebilir","te":"Adjective","tt":"Sıfat","de":"That can be noticed or seen","dt":"Fark edilebilen veya görülebilen","e1":"Observable changes in the climate.","e1t":"İklimdeki gözlemlenebilir değişiklikler.","e2":"Easily observable.","e2t":"Kolayca gözlemlenebilir."},{"w":"observant","tr":"dikkatli / kurallara uyan / keskin gözlü","te":"Adjective","tt":"Sıfat","de":"Good or quick at noticing things; or following laws","dt":"Şeyleri fark etme konusunda iyi/hızlı; veya kuralları takip eden","e1":"He is a very observant child.","e1t":"O çok dikkatli bir çocuktur.","e2":"Observant Jews.","e2t":"Kurallara bağlı Yahudiler."},{"w":"observatory","tr":"gözlemevi / rasathane","te":"Noun","tt":"İsim","de":"A building from which scientists study the stars or weather","dt":"Bilim insanlarının yıldızları veya havayı incelediği bina","e1":"Kandilli Observatory.","e1t":"Kandilli Rasathanesi.","e2":"An astronomical observatory.","e2t":"Astronomik gözlemevi."},{"w":"obsess","tr":"takıntı yapmak / aklına takılmak / musallat olmak","te":"Verb","tt":"Fiil","de":"To think about something all the time","dt":"Sürekli bir şeyi düşünmek","e1":"She obsesses about her weight.","e1t":"Kilosuna takıntı yapıyor.","e2":"Don't let your failures obsess you.","e2t":"Başarısızlıklarının zihnine musallat olmasına izin verme."},{"w":"obstinate","tr":"inatçı / dikbaşlı","te":"Adjective","tt":"Sıfat","de":"Refusing to change your opinion or behavior","dt":"Fikrini veya davranışını değiştirmeyi reddeden","e1":"He is as obstinate as a mule.","e1t":"Katır kadar inatçıdır.","e2":"Obstinate resistance.","e2t":"İnatçı direnç."},{"w":"obstruct","tr":"engellemek / tıkanmak / yoluna çıkmak","te":"Verb","tt":"Fiil","de":"To block a road or path; or to prevent progress","dt":"Bir yolu veya geçidi kapatmak; veya ilerlemeyi engellemek","e1":"The fallen tree obstructed the road.","e1t":"Devrilen ağaç yolu kapattı (engelledi).","e2":"To obstruct justice.","e2t":"Adaleti yanıltmak (engellemek)."},{"w":"obtrusive","tr":"göze batan / rahatsız edici derecede belirgin","te":"Adjective","tt":"Sıfat","de":"Noticeable in an unpleasant or annoying way","dt":"Nahoş veya rahatsız edici bir şekilde fark edilen","e1":"The logo was small and not too obtrusive.","e1t":"Logo küçüktü ve çok fazla göze batmıyordu.","e2":"Obtrusive music.","e2t":"Rahatsız edici (gürültülü) müzik."},{"w":"occupant","tr":"oturan / sakin / işgalci","te":"Noun","tt":"İsim","de":"A person who lives or works in a room or building","dt":"Bir odada veya binada yaşayan ya da çalışan kişi","e1":"The previous occupants of the house.","e1t":"Evin önceki sakinleri (oturanları).","e2":"All occupants of the vehicle were injured.","e2t":"Araçtaki tüm yolcular yaralandı."},{"w":"odd","tr":"tuhaf / garip / tek (sayı)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Strange or unexpected; or a number that cannot be divided by two","dt":"Garip veya beklenmedik; veya ikiye bölünemeyen sayı","e1":"He has some very odd habits.","e1t":"Onun bazı çok tuhaf alışkanlıkları var.","e2":"One, three, and five are odd numbers.","e2t":"Bir, üç ve beş tek sayılardır."},{"w":"offence / offense","tr":"suç / saldırı / gücenme","te":"Noun","tt":"İsim","de":"An illegal act; or a feeling of being hurt or insulted","dt":"Yasadışı eylem; veya incinme ya da hakarete uğrama hissi","e1":"A serious criminal offence.","e1t":"Ciddi bir ceza suçu.","e2":"No offence intended.","e2t":"Gücendirmek (kırmak) istemedim."},{"w":"omen","tr":"alamet / işaret / belirti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sign of what will happen in the future","dt":"Gelecekte ne olacağına dair bir işaret","e1":"A good omen for the future.","e1t":"Gelecek için iyi bir alamet.","e2":"The black cat was seen as a bad omen.","e2t":"Kara kedi kötü bir alamet olarak görüldü."},{"w":"ominous","tr":"uğursuz / tehditkar","te":"Adjective","tt":"Sıfat","de":"Suggesting that something unpleasant is about to happen","dt":"Nahoş bir şeyin gerçekleşmek üzere olduğunu düşündüren","e1":"Those black clouds look ominous.","e1t":"Şu kara bulutlar uğursuz (tehditkar) görünüyor.","e2":"An ominous silence.","e2t":"Uğursuz bir sessizlik."},{"w":"omission","tr":"ihmal / çıkarma / eksiklik","te":"Noun","tt":"İsim","de":"The act of not including something","dt":"Bir şeyi dahil etmeme (dışarıda bırakma) eylemi","e1":"The omission of his name from the list was a mistake.","e1t":"Adının listeden çıkarılması (dahil edilmemesi) bir hataydı.","e2":"Errors and omissions.","e2t":"Hatalar ve eksiklikler."},{"w":"omnipotent","tr":"her şeye gücü yeten / kadir","te":"i mutlak","tt":"Adjective","de":"Sıfat","dt":"Having unlimited power and able to do anything","e1":"Sınırsız gücü olan ve her şeyi yapabilen","e1t":"An omnipotent god.","e2":"Her şeye gücü yeten bir tanrı.","e2t":"He thinks he is omnipotent."},{"w":"onus","tr":"yükümlülük / sorumluluk / yük","te":"Noun","tt":"İsim","de":"The responsibility or duty to do something","dt":"Bir şeyi yapma sorumluluğu veya görevi","e1":"The onus is on the landlord to repair the roof.","e1t":"Çatıyı tamir etme yükümlülüğü ev sahibine aittir.","e2":"To carry the onus of proof.","e2t":"İspat yükümlülüğünü taşımak."},{"w":"opaque","tr":"opak / mat / saydam olmayan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not able to be seen through; or difficult to understand","dt":"İçinden bakılamayan (ışık geçirmeyen); veya anlaşılması zor","e1":"Opaque glass.","e1t":"Opak (mat) cam.","e2":"The jargon made the report opaque.","e2t":"Jargon, raporu anlaşılmaz (muğlak) kıldı."},{"w":"opportune","tr":"uygun (zaman) / elverişli","te":"Adjective","tt":"Sıfat","de":"(Of a time) suitable or right for a particular purpose","dt":"(Zaman için) belirli bir amaç için uygun veya doğru olan","e1":"At an opportune moment.","e1t":"Uygun bir anda.","e2":"The offer came at a very opportune time.","e2t":"Teklif çok uygun bir zamanda geldi."},{"w":"oppress","tr":"baskı yapmak / zulmetmek","te":"Verb","tt":"Fiil","de":"To govern people in an unfair and cruel way","dt":"İnsanları adaletsiz ve zalim bir şekilde yönetmek","e1":"The people were oppressed by a cruel dictator.","e1t":"Halk zalim bir diktatör tarafından baskı altındaydı (zulüm görüyordu).","e2":"To feel oppressed by the heat.","e2t":"Sıcaktan bunalmış (baskı altında) hissetmek."},{"w":"optic","tr":"optik / görme ile ilgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to light or the eye","dt":"Işık veya göz ile ilgili","e1":"Optic nerve.","e1t":"Görme siniri.","e2":"Fiber optics.","e2t":"Fiber optik."},{"w":"optimal","tr":"en uygun / en elverişli / optimum","te":"Adjective","tt":"Sıfat","de":"The best or most effective possible","dt":"Mümkün olan en iyi veya en etkili","e1":"Optimal conditions for growth.","e1t":"Büyüme için en uygun koşullar.","e2":"To achieve the optimal result.","e2t":"En iyi sonucu elde etmek."},{"w":"optimism","tr":"iyimserlik / optimizm","te":"Noun","tt":"İsim","de":"A feeling that good things will happen in the future","dt":"Gelecekte iyi şeylerin olacağına dair his","e1":"There is cautious optimism about the economy.","e1t":"Ekonomi hakkında temkinli bir iyimserlik var.","e2":"To maintain your optimism.","e2t":"İyimserliğini korumak."},{"w":"ordeal","tr":"çile / zorlu deneyim / sınav","te":"Noun","tt":"İsim","de":"A very difficult or unpleasant experience","dt":"Çok zorlu veya nahoş bir deneyim","e1":"They survived a terrible ordeal in the desert.","e1t":"Çölde korkunç bir çileden (zorlu deneyimden) sağ kurtuldular.","e2":"To go through an ordeal.","e2t":"Bir sınavdan (zorluktan) geçmek."},{"w":"organ","tr":"organ / org (müzik aleti) / yayın organı","te":"Noun","tt":"İsim","de":"A part of the body with a specific function; or a musical instrument","dt":"Belirli bir işlevi olan vücut parçası; veya müzik aleti","e1":"The heart is a vital organ.","e1t":"Kalp hayati bir organdır.","e2":"To play the pipe organ.","e2t":"Kilise orgu çalmak."},{"w":"orient","tr":"yönlendirmek / uyum sağlamak / Doğu","te":"Verb/Noun/Adj","tt":"To discover your position; or relating to East Asian countries","de":"Konumunu belirlemek; veya Doğu Asya ülkeleriyle ilgili","dt":"It took him a while to orient himself in the new city.","e1":"Yeni şehirde yolunu bulması (yönünü belirlemesi) biraz zaman aldı.","e1t":"The Orient (East Asia).","e2":"Şark (Doğu Asya).","e2t":""},{"w":"orthodox","tr":"ortodoks / geleneksel / kabul görmüş","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Following traditional beliefs or practices","dt":"Geleneksel inanç veya uygulamaları takip eden","e1":"Orthodox medicine.","e1t":"Geleneksel (yaygın) tıp.","e2":"Orthodox Church.","e2t":"Ortodoks Kilisesi."},{"w":"oscillate","tr":"salınmak / tereddüt etmek / gidip gelmek","te":"Verb","tt":"Fiil","de":"To move back and forth between two points","dt":"İki nokta arasında gidip gelmek","e1":"The needle on the gauge began to oscillate.","e1t":"Göstergedeki ibre salınmaya (gidip gelmeye) başladı.","e2":"He oscillates between hope and fear.","e2t":"Umut ve korku arasında gidip geliyor."},{"w":"ostentatious","tr":"gösterişli / frapan / şatafatlı","te":"Adjective","tt":"Sıfat","de":"Intended to attract admiration or notice","dt":"Hayranlık veya dikkat çekmek amaçlı","e1":"An ostentatious lifestyle.","e1t":"Gösterişli (şatafatlı) bir yaşam tarzı.","e2":"Ostentatious jewelry.","e2t":"Gösterişli mücevherler."},{"w":"ostracize / ostracise","tr":"dışlamak / toplumdan sürmek","te":"Verb","tt":"Fiil","de":"To exclude someone from a group","dt":"Birini bir gruptan dışlamak","e1":"He was ostracized by his colleagues.","e1t":"Meslektaşları tarafından dışlandı.","e2":"To ostracize a former member.","e2t":"Eski bir üyeyi aforoz etmek (dışlamak)."},{"w":"otherwise","tr":"aksi takdirde / yoksa / başka türlü","te":"Adverb/Adj/Conj","tt":"If not; or in a different way","de":"Eğer öyle olmazsa; veya farklı bir şekilde","dt":"Hurry up, otherwise we'll be late.","e1":"Acele et, aksi takdirde (yoksa) geç kalacağız.","e1t":"She is otherwise a very healthy person.","e2":"Diğer yönlerden (başka türlü) çok sağlıklı biridir.","e2t":""},{"w":"outbreak","tr":"salgın / patlak verme","te":"Noun","tt":"İsim","de":"A sudden start of something unpleasant, like a disease","dt":"Hastalık gibi nahoş bir şeyin aniden başlaması","e1":"An outbreak of flu.","e1t":"Grip salgını.","e2":"The outbreak of war.","e2t":"Savaşın patlak vermesi."},{"w":"outburst","tr":"patlama (duygu) / fışkırma","te":"Noun","tt":"İsim","de":"A sudden strong expression of emotion","dt":"Ani ve güçlü duygu ifadesi","e1":"An outburst of anger.","e1t":"Öfke patlaması.","e2":"Emotional outburst.","e2t":"Duygusal boşalma (patlama)."},{"w":"outcast","tr":"dışlanmış / toplumdan dışlanan kişi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has been rejected by society or a group","dt":"Toplum veya bir grup tarafından reddedilmiş kişi","e1":"He felt like a social outcast.","e1t":"Kendini sosyal bir dışlanmış gibi hissetti.","e2":"An outcast from the family.","e2t":"Aileden dışlanan kişi."},{"w":"outcry","tr":"feryat / şiddetli protesto","te":"Noun","tt":"İsim","de":"A strong expression of public anger or disapproval","dt":"Halkın öfkesinin veya onaylamamasının güçlü ifadesi","e1":"There was a public outcry against the new taxes.","e1t":"Yeni vergilere karşı şiddetli bir halk protestosu (feryadı) yükseldi.","e2":"To cause an international outcry.","e2t":"Uluslararası bir tepkiye yol açmak."},{"w":"outdated","tr":"eski moda / miadı dolmuş / geçersiz","te":"Adjective","tt":"Sıfat","de":"Old","dt":"fashioned and no longer useful or correct","e1":"Eski moda ve artık yararlı veya doğru olmayan","e1t":"Outdated technology.","e2":"Miadı dolmuş (eski) teknoloji.","e2t":"Your information is outdated."},{"w":"outdo","tr":"geride bırakmak / daha iyisini yapmak","te":"Verb","tt":"Fiil","de":"To be better than someone else","dt":"Başkasından daha iyi olmak","e1":"He tried to outdo his brother in everything.","e1t":"Her konuda kardeşinden daha iyi olmaya (onu geride bırakmaya) çalıştı.","e2":"To outdo expectations.","e2t":"Beklentileri aşmak."},{"w":"outing","tr":"gezinti / kısa tur / ifşa (gizli bir durumu)","te":"Noun","tt":"İsim","de":"A short journey for pleasure; or revealing a secret","dt":"Zevk için yapılan kısa yolculuk; veya bir sırrı ifşa etme","e1":"A family outing to the beach.","e1t":"Plaja bir aile gezintisi.","e2":"The actor's public outing.","e2t":"Aktörün (özel durumunun) kamuoyuna ifşası."},{"w":"outlandish","tr":"tuhaf / garip / alışılmadık","te":"Adjective","tt":"Sıfat","de":"Strange and unusual and difficult to accept","dt":"Garip, alışılmadık ve kabul edilmesi zor","e1":"Outlandish clothes.","e1t":"Tuhaf kıyafetler.","e2":"An outlandish excuse.","e2t":"Alışılmadık (saçma) bir bahane."},{"w":"outlaw","tr":"haydut / yasaklamak / kanun kaçağı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who has broken the law; or to make something illegal","dt":"Yasayı çiğnemiş kişi; veya bir şeyi yasadışı yapmak","e1":"Robin Hood was a famous outlaw.","e1t":"Robin Hood ünlü bir hayduttu (kanun kaçağıydı).","e2":"Smoking in public places should be outlawed.","e2t":"Kamusal alanlarda sigara içmek yasaklanmalıdır."},{"w":"outlet","tr":"çıkış / priz / bayi / dışa vurma yolu","te":"Noun","tt":"İsim","de":"A way for something to go out; or a place that sells goods","dt":"Bir şeyin dışarı çıkma yolu; veya mal satan yer","e1":"Retail outlet.","e1t":"Perakende satış noktası (bayi).","e2":"Writing is a creative outlet for him.","e2t":"Yazmak onun için yaratıcı bir dışa vurma yoludur."},{"w":"outnumber","tr":"sayıca üstün olmak","te":"Verb","tt":"Fiil","de":"To be greater in number than someone or something","dt":"Birinden veya bir şeyden sayıca daha fazla olmak","e1":"The girls outnumber the boys in this class.","e1t":"Bu sınıfta kızlar erkeklerden sayıca daha fazla.","e2":"To be heavily outnumbered.","e2t":"Sayıca çok geride kalmak."},{"w":"outrage","tr":"öfke / rezalet / hakaret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling of anger or shock; or a very bad act","dt":"Güçlü öfke veya şok hissi; veya çok kötü bir eylem","e1":"The news caused widespread public outrage.","e1t":"Haberler halk arasında yaygın bir öfkeye yol açtı.","e2":"A moral outrage.","e2t":"Ahlaki bir rezalet."},{"w":"outrageous","tr":"rezil / aşırı / şok edici","te":"Adjective","tt":"Sıfat","de":"Shocking and morally unacceptable; or very unusual","dt":"Şok edici ve ahlaken kabul edilemez; veya çok sıra dışı","e1":"Outrageous behavior.","e1t":"Rezil (şok edici) davranış.","e2":"An outrageous price.","e2t":"Aşırı (fahiş) bir fiyat."},{"w":"outset","tr":"başlangıç","te":"Noun","tt":"İsim","de":"The beginning of something","dt":"Bir şeyin başlangıcı","e1":"At the outset of the project.","e1t":"Projenin başlangıcında.","e2":"You should have told me from the outset.","e2t":"Bana en baştan söylemeliydin."},{"w":"outskirts","tr":"kenar mahalleler / şehrin dışı","te":"Noun","tt":"İsim","de":"The outer parts of a town or city","dt":"Bir kasabanın veya şehrin dış kısımları","e1":"They live on the outskirts of Istanbul.","e1t":"İstanbul'un dış kısımlarında (kenar mahallelerinde) yaşıyorlar.","e2":"Outskirts of the forest.","e2t":"Ormanın kenarı."},{"w":"outspoken","tr":"açık sözlü / sözünü sakınmayan","te":"Adjective","tt":"Sıfat","de":"Expressing strong opinions very directly","dt":"Güçlü fikirlerini çok doğrudan ifade eden","e1":"He is an outspoken critic of the government.","e1t":"O, hükümetin açık sözlü (sert) bir eleştirmenidir.","e2":"To be very outspoken.","e2t":"Çok açık sözlü olmak."},{"w":"outward","tr":"dışa doğru / dış / harici","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Relating to how people or things seem on the outside","dt":"İnsanların veya şeylerin dışarıdan nasıl göründüğüyle ilgili","e1":"Outward appearance.","e1t":"Dış görünüş.","e2":"Outward journey.","e2t":"Gidiş yolculuğu."},{"w":"outweigh","tr":"daha ağır basmak / daha önemli olmak","te":"Verb","tt":"Fiil","de":"To be greater or more important than something else","dt":"Başka bir şeyden daha büyük veya daha önemli olmak","e1":"The benefits outweigh the risks.","e1t":"Faydalar risklerden daha ağır basıyor.","e2":"The advantages far outweigh the disadvantages.","e2t":"Avantajlar dezavantajlardan çok daha ağır basıyor."},{"w":"oval","tr":"oval / yumurta şeklinde","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Shaped like an egg","dt":"Yumurta şeklinde","e1":"An oval face.","e1t":"Oval bir yüz.","e2":"An oval table.","e2t":"Oval bir masa."},{"w":"ovation","tr":"alkış / tezahürat","te":"Noun","tt":"İsim","de":"A sustained and enthusiastic show of appreciation from an audience","dt":"İzleyicilerden gelen sürekli ve coşkulu takdir gösterisi","e1":"Standing ovation.","e1t":"Ayakta alkışlama.","e2":"The speaker received a loud ovation.","e2t":"Konuşmacı büyük bir alkış (tezahürat) aldı."},{"w":"overcast","tr":"bulutlu / kapalı (hava)","te":"Adjective/Noun/Verb","tt":"(Of the sky) covered with clouds","de":"(Gökyüzü için) bulutlarla kaplı","dt":"An overcast sky.","e1":"Kapalı (bulutlu) bir gökyüzü.","e1t":"The weather will be mostly overcast today.","e2":"Bugün hava çoğunlukla kapalı olacak.","e2t":""},{"w":"overcharge","tr":"fazla ücret almak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To ask someone to pay too much money for something","dt":"Birinden bir şey için çok fazla para istemek","e1":"The taxi driver tried to overcharge me.","e1t":"Taksi şoförü benden fazla ücret almaya çalıştı.","e2":"To avoid being overcharged.","e2t":"Fazla ücret ödemekten kaçınmak."},{"w":"overcrowded","tr":"aşırı kalabalık","te":"Adjective","tt":"Sıfat","de":"Containing too many people or things","dt":"Çok fazla insan veya şey barındıran","e1":"Overcrowded prisons.","e1t":"Aşırı kalabalık hapishaneler.","e2":"The bus was overcrowded.","e2t":"Otobüs aşırı kalabalıktı."},{"w":"overdue","tr":"vadesi geçmiş / gecikmiş","te":"Adjective","tt":"Sıfat","de":"Not done or happening when expected or needed","dt":"Beklenen veya gereken zamanda yapılmamış ya da gerçekleşmemiş","e1":"An overdue bill.","e1t":"Vadesi geçmiş fatura.","e2":"Reform is long overdue.","e2t":"Reformun zamanı çoktan geçti (gecikti)."},{"w":"overflow","tr":"taşmak / aşırı kalabalık olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To flow over the edge of a container","dt":"Bir kabın kenarından dışarı akmak","e1":"The river overflowed its banks.","e1t":"Nehir yatağından taştı.","e2":"The hospital is overflowing with patients.","e2t":"Hastane hastalarla dolup taşıyor."},{"w":"overhaul","tr":"elden geçirmek (bakım) / revizyon / tamir","te":"Verb/Noun","tt":"Fiil/İsim","de":"To examine a machine or system and repair or improve it","dt":"Bir makineyi veya sistemi inceleyip tamir etmek veya geliştirmek","e1":"The engine needs a major overhaul.","e1t":"Motorun kapsamlı bir bakımdan (revizyondan) geçmesi gerekiyor.","e2":"To overhaul the education system.","e2t":"Eğitim sistemini elden geçirmek (reforme etmek)."},{"w":"overhead","tr":"genel giderler / baş üstü / havai","te":"Noun/Adj/Adv","tt":"Costs that are not directly related to production; or above you","de":"Üretimle doğrudan ilgili olmayan masraflar; veya başın üzerinde","dt":"The company is trying to reduce its overheads.","e1":"Şirket genel giderlerini azaltmaya çalışıyor.","e1t":"Planes flying overhead.","e2":"Başımızın üzerinden (havadan) geçen uçaklar.","e2t":""},{"w":"overhear","tr":"kulak misafiri olmak / gizlice duymak","te":"Verb","tt":"Fiil","de":"To hear what other people are saying without meaning to","dt":"İstemeden başkalarının ne dediğini duymak","e1":"I overheard them talking about the new project.","e1t":"Yeni proje hakkında konuştuklarına kulak misafiri oldum.","e2":"To overhear a secret.","e2t":"Bir sırrı gizlice duymak."},{"w":"overlap","tr":"örtüşmek / üst üste binmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cover part of the same area or to happen at the same time","dt":"Aynı alanın bir kısmını kaplamak veya aynı zamanda gerçekleşmek","e1":"Our interests overlap in many areas.","e1t":"İlgi alanlarımız birçok noktada örtüşüyor.","e2":"The tiles should overlap each other.","e2t":"Fayanslar birbirinin üzerine binmeli."},{"w":"overlay","tr":"kaplamak / üstüne koymak / tabaka","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cover something with a layer of something else","dt":"Bir şeyi başka bir tabaka ile kaplamak","e1":"To overlay a map with digital data.","e1t":"Bir haritayı dijital verilerle kaplamak (üst üste bindirmek).","e2":"A gold overlay.","e2t":"Altın kaplama."},{"w":"overload","tr":"aşırı yüklemek / aşırı yük","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put too much of something on or into something","dt":"Bir şeyin üzerine veya içine çok fazla şey koymak","e1":"Don't overload the washing machine.","e1t":"Çamaşır makinesini aşırı yüklemeyin.","e2":"Information overload.","e2t":"Bilgi yüklemesi (aşırı bilgi yükü)."},{"w":"overly","tr":"fazlasıyla / aşırı derecede","te":"Adverb","tt":"Zarf","de":"Too; very","dt":"Çok; aşırı","e1":"He is overly sensitive to criticism.","e1t":"Eleştiriye karşı fazlasıyla (aşırı) hassastır.","e2":"An overly complicated plan.","e2t":"Aşırı derecede karmaşık bir plan."},{"w":"overnight","tr":"bir gecede / geceleyin / aniden","te":"Adverb/Adjective","tt":"During the night; or suddenly","de":"Gece boyunca; veya aniden","dt":"They stayed overnight in London.","e1":"Londra'da gecelediler.","e1t":"He became famous overnight.","e2":"Bir gecede (aniden) ünlü oldu.","e2t":""},{"w":"overpower","tr":"etkisiz hale getirmek / bastırmak / ağır gelmek","te":"Verb","tt":"Fiil","de":"To defeat someone by having greater power","dt":"Daha büyük bir güç kullanarak birini yenmek","e1":"The police managed to overpower the gunman.","e1t":"Polis silahlı adamı etkisiz hale getirmeyi başardı.","e2":"The smell of onions overpowered everything.","e2t":"Soğan kokusu her şeye baskın geldi (ağır geldi)."},{"w":"overrate","tr":"abartmak / olduğundan fazla değer vermek","te":"Verb","tt":"Fiil","de":"To have too high an opinion of someone or something","dt":"Biri veya bir şey hakkında çok yüksek bir görüşe sahip olmak","e1":"I think that movie is highly overrated.","e1t":"Bence o film çok abartılıyor (hak ettiğinden fazla değer görüyor).","e2":"To overrate your own abilities.","e2t":"Kendi yeteneklerini olduğundan üstün görmek."},{"w":"overrule","tr":"reddetmek (kararı) / geçersiz saymak","te":"Verb","tt":"Fiil","de":"To change a decision using official power","dt":"Resmi gücü kullanarak bir kararı değiştirmek","e1":"The judge overruled the objection.","e1t":"Yargıç itirazı reddetti (geçersiz saydı).","e2":"The board can overrule the manager's decision.","e2t":"Kurul, müdürün kararını bozabilir."},{"w":"overrun","tr":"istila etmek / taşmak / süreyi aşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fill or take control of a place quickly","dt":"Bir yeri hızla doldurmak veya kontrolünü ele geçirmek","e1":"The garden was overrun with weeds.","e1t":"Bahçeyi yabani otlar istila etmişti.","e2":"The meeting overran by twenty minutes.","e2t":"Toplantı süresini yirmi dakika aştı."},{"w":"oversee","tr":"denetlemek / gözetmek","te":"Verb","tt":"Fiil","de":"To watch or organize a job or an activity","dt":"Bir işi veya faaliyeti izlemek ya da organize etmek","e1":"He was hired to oversee the construction project.","e1t":"İnşaat projesini denetlemek (yönetmek) için işe alındı.","e2":"To oversee a department.","e2t":"Bir departmanı gözetmek."},{"w":"oversight","tr":"gözetim / dalgınlık / hata","te":"Noun","tt":"İsim","de":"Responsibility for a job; or a mistake from not noticing","dt":"Bir işin sorumluluğu; veya fark etmemekten kaynaklanan hata","e1":"The committee has oversight of the budget.","e1t":"Komitenin bütçe üzerinde gözetim yetkisi var.","e2":"I'm sorry, it was an oversight on my part.","e2t":"Üzgünüm, benim tarafımdan bir dalgınlıktı (gözden kaçmıştı)."},{"w":"overstate","tr":"abartmak / mübalağa etmek","te":"Verb","tt":"Fiil","de":"To describe something as larger or more important than it is","dt":"Bir şeyi olduğundan daha büyük veya önemliymiş gibi anlatmak","e1":"It is impossible to overstate the importance of education.","e1t":"Eğitimin önemini abartmak (fazla söylemek) mümkün değildir.","e2":"To overstate a claim.","e2t":"Bir iddiayı abartmak."},{"w":"overtake","tr":"sollamak / geride bırakmak / başına gelmek","te":"Verb","tt":"Fiil","de":"To go past a slower vehicle; or to become more successful","dt":"Daha yavaş bir aracı geçmek; veya daha başarılı olmak","e1":"He overtook the truck on the highway.","e1t":"Otoyolda kamyonu solladı.","e2":"Germany has overtaken Japan in car production.","e2t":"Almanya otomobil üretiminde Japonya'yı geride bıraktı."},{"w":"overthrow","tr":"devirmek (hükümet vb.) / yıkmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove a leader or government by force","dt":"Bir lideri veya hükümeti zorla görevden almak","e1":"The government was overthrown in a military coup.","e1t":"Hükümet askeri bir darbe ile devrildi.","e2":"To overthrow a dictator.","e2t":"Bir diktatörü devirmek."},{"w":"overtime","tr":"mesai / fazla mesai","te":"Noun/Adverb","tt":"Time worked in addition to regular hours","de":"Normal çalışma saatlerine ek olarak çalışılan süre","dt":"He is working a lot of overtime this month.","e1":"Bu ay çok fazla mesai yapıyor.","e1t":"Overtime pay.","e2":"Mesai ücreti.","e2t":""},{"w":"overturn","tr":"devirmek / (kararı) bozmak / ters dönmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn upside down; or to change a legal decision","dt":"Baş aşağı çevirmek; veya yasal bir kararı değiştirmek","e1":"The car hit a tree and overturned.","e1t":"Araba bir ağaca çarptı ve devrildi.","e2":"The Supreme Court overturned the decision.","e2t":"Yargıtay kararı bozdu (iptal etti)."},{"w":"overwhelm","tr":"bunaltmak / etkisi altına almak / ezmek","te":"Verb","tt":"Fiil","de":"To cause someone to feel sudden strong emotion","dt":"Birine aniden güçlü duygular hissettirmek (boğmak)","e1":"I was overwhelmed by all the flowers and cards.","e1t":"Tüm çiçekler ve kartlar karşısında duygulandım (bunalmış gibi oldum).","e2":"Work is starting to overwhelm me.","e2t":"İşler beni bunaltmaya (ezmeye) başlıyor."},{"w":"overwhelming","tr":"bunaltıcı / ezici / çok büyük","te":"Adjective","tt":"Sıfat","de":"Very great or very strong","dt":"Çok büyük veya çok güçlü","e1":"An overwhelming majority voted for the change.","e1t":"Ezici bir çoğunluk değişim lehine oy verdi.","e2":"Overwhelming evidence.","e2t":"Çok güçlü (ezici) kanıt."},{"w":"ozone","tr":"ozon","te":"Noun","tt":"İsim","de":"A form of oxygen that protects the Earth from the sun","dt":"Dünya'yı güneşten koruyan bir oksijen formu","e1":"The ozone layer.","e1t":"Ozon tabakası.","e2":"Ozone depletion.","e2t":"Ozon tabakasının incelmesi."},{"w":"pacify","tr":"sakinleştirmek / yatıştırmak / huzura kavuşturmak","te":"Verb","tt":"Fiil","de":"To cause someone who is angry to become calm","dt":"Öfkeli birinin sakinleşmesini sağlamak","e1":"He tried to pacify the crying baby.","e1t":"Ağlayan bebeği sakinleştirmeye çalıştı.","e2":"Measures to pacify the region.","e2t":"Bölgeyi huzura kavuşturma (yatıştırma) önlemleri."},{"w":"pact","tr":"antlaşma / sözleşme / pakt","te":"Noun","tt":"İsim","de":"A formal agreement between two people or groups","dt":"İki kişi veya grup arasındaki resmi anlaşma","e1":"A non","e1t":"aggression pact.","e2":"Saldırmazlık paktı (anlaşması).","e2t":"They made a pact to tell the truth."},{"w":"pageant","tr":"gösteri / resmi geçit / güzellik yarışması","te":"Noun","tt":"İsim","de":"A public show or ceremony; or a competition","dt":"Halka açık gösteri veya tören; veya yarışma","e1":"A historical pageant.","e1t":"Tarihsel bir resmi geçit (gösteri).","e2":"Beauty pageant.","e2t":"Güzellik yarışması."},{"w":"pail","tr":"kova / kova dolusu","te":"Noun","tt":"İsim","de":"A bucket","dt":"Kova","e1":"A milk pail.","e1t":"Süt kovası.","e2":"They carried pails of water.","e2t":"Kovalarla su taşıdılar."},{"w":"painstaking","tr":"titiz / özenli / zahmetli","te":"Adjective","tt":"Sıfat","de":"Done with a lot of care and effort","dt":"Çok özen ve çaba ile yapılan","e1":"It was a painstaking task to restore the old painting.","e1t":"Eski tabloyu restore etmek titiz (zahmetli) bir işti.","e2":"Painstaking research.","e2t":"Çok titiz bir araştırma."},{"w":"palatable","tr":"lezzetli / makul / kabul edilebilir","te":"Adjective","tt":"Sıfat","de":"(Of food) having a pleasant taste; or acceptable","dt":"(Yemek için) lezzetli; veya kabul edilebilir","e1":"A very palatable meal.","e1t":"Çok lezzetli bir yemek.","e2":"The proposal was not palatable to the workers.","e2t":"Öneri işçiler için makul (kabul edilebilir) değildi."},{"w":"pamphlet","tr":"broşür / kitapçık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small book with a paper cover that gives information","dt":"Bilgi veren kağıt kapaklı küçük kitapçık","e1":"A pamphlet on healthy eating.","e1t":"Sağlıklı beslenme üzerine bir broşür.","e2":"Political pamphlets.","e2t":"Siyasi kitapçıklar."},{"w":"pant","tr":"nefes nefese kalmak / solumak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To breathe quickly and loudly","dt":"Hızlı ve sesli nefes almak","e1":"He was panting after the long run.","e1t":"Uzun koşudan sonra nefes nefese kalmıştı.","e2":"To pant for breath.","e2t":"Nefes alabilmek için solumak."},{"w":"par","tr":"eşitlik / standart / başa baş","te":"Noun/Adjective/Verb","tt":"An equal level; or a standard in golf","de":"Eşit seviye; veya golfte standart vuruş sayısı","dt":"His English is on a par with a native speaker.","e1":"İngilizcesi bir ana dil konuşmacısıyla aynı seviyededir (başa baştır).","e1t":"Below par (not feeling well).","e2":"Pek iyi hissetmemek (formunda olmamak).","e2t":""},{"w":"parachute","tr":"paraşüt / paraşütle atlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large piece of cloth used for jumping from a plane","dt":"Uçaktan atlamak için kullanılan geniş kumaş parçası","e1":"To jump with a parachute.","e1t":"Paraşütle atlamak.","e2":"A golden parachute (business term).","e2t":"Altın paraşüt (yöneticilere verilen yüksek tazminat)."},{"w":"paradigm","tr":"paradigma / örnek / model","te":"Noun","tt":"İsim","de":"A model of something or a very clear example","dt":"Bir şeyin modeli veya çok net bir örneği","e1":"A new paradigm for education.","e1t":"Eğitim için yeni bir paradigma (model).","e2":"Shift in paradigm.","e2t":"Paradigma kayması."},{"w":"paradise","tr":"cennet / eşsiz yer","te":"Noun","tt":"İsim","de":"A perfect place where everyone is happy","dt":"Herkesin mutlu olduğu mükemmel yer","e1":"A tropical paradise.","e1t":"Tropikal bir cennet.","e2":"To live in paradise.","e2t":"Cennette yaşamak."},{"w":"paradox","tr":"paradoks / çelişki","te":"Noun","tt":"İsim","de":"A situation that seems impossible because it has two opposite features","dt":"İki zıt özelliği olduğu için imkansız görünen durum","e1":"It's a paradox that such a wealthy country has so many poor people.","e1t":"Bu kadar zengin bir ülkenin bu kadar çok fakir insana sahip olması bir paradokstur.","e2":"Time travel paradox.","e2t":"Zaman yolculuğu paradoksu."},{"w":"paralysis","tr":"felç / inme / duraksama","te":"Noun","tt":"İsim","de":"The inability to move all or part of the body","dt":"Vücudun tamamını veya bir kısmını hareket ettirememe","e1":"The accident left him with permanent paralysis.","e1t":"Kaza onda kalıcı felç bıraktı.","e2":"Policy paralysis (in politics).","e2t":"Politika tıkanıklığı (duraksama)."},{"w":"paralyze / paralyse","tr":"felç etmek / dondurmak / durdurmak","te":"Verb","tt":"Fiil","de":"To cause someone to lose the ability to move","dt":"Birinin hareket yeteneğini kaybetmesine neden olmak","e1":"The poison paralyzes the muscles.","e1t":"Zehir kasları felç eder.","e2":"The city was paralyzed by the snowstorm.","e2t":"Şehir kar fırtınası nedeniyle felç oldu (durdu)."},{"w":"parameter","tr":"parametre / değişken / kısıt","te":"Noun","tt":"İsim","de":"A set of facts that decides how something is done","dt":"Bir şeyin nasıl yapılacağına karar veren veriler seti","e1":"To define the parameters of the study.","e1t":"Çalışmanın parametrelerini (kapsamını/kısıtlarını) belirlemek.","e2":"Within certain parameters.","e2t":"Belirli parametreler dahilinde."},{"w":"paramount","tr":"en önemli / üstün / en yüce","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"More important than anything else","dt":"Diğer her şeyden daha önemli","e1":"Safety is of paramount importance.","e1t":"Güvenlik en yüksek öneme sahiptir.","e2":"Our paramount concern is the children.","e2t":"En öncelikli (üstün) kaygımız çocuklardır."},{"w":"paranoia","tr":"paranoya","te":"Noun","tt":"İsim","de":"An extreme and unreasonable feeling that other people are trying to harm you","dt":"Başkalarının size zarar vermeye çalıştığına dair aşırı ve mantıksız his","e1":"He suffers from paranoia.","e1t":"Paranoya çekiyor.","e2":"Political paranoia.","e2t":"Siyasi paranoya."},{"w":"parasite","tr":"parazit / asalak","te":"Noun","tt":"İsim","de":"An animal or plant that lives on or inside another animal","dt":"Başka bir canlının üzerinde veya içinde yaşayan canlı","e1":"Intestinal parasites.","e1t":"Bağırsak parazitleri.","e2":"He is a parasite, living off his parents' money.","e2t":"O bir asalak, ailesinin parasıyla geçiniyor."},{"w":"parish","tr":"kilise bölgesi / mahalle","te":"Noun","tt":"İsim","de":"An area that has its own church and priest","dt":"Kendi kilisesi ve rahibi olan bölge","e1":"Our parish church.","e1t":"Bizim mahalle (bölge) kilisemiz.","e2":"Parish priest.","e2t":"Mahalle rahibi."},{"w":"parity","tr":"eşitlik / denklik","te":"Noun","tt":"İsim","de":"The state of being equal, especially in status or pay","dt":"Özellikle statü veya maaşta eşit olma durumu","e1":"Gender parity.","e1t":"Cinsiyet eşitliği.","e2":"To achieve parity between the two currencies.","e2t":"İki para birimi arasında denklik sağlamak."},{"w":"parliament","tr":"parlamento / meclis","te":"Noun","tt":"İsim","de":"A group of people who are elected to make a country's laws","dt":"Bir ülkenin yasalarını yapmak için seçilen insanlar grubu","e1":"The Turkish Parliament.","e1t":"Türkiye Büyük Millet Meclisi.","e2":"A member of parliament (MP).","e2t":"Milletvekili."},{"w":"parlor / parlour","tr":"salon / dükkan / oda","te":"Noun","tt":"İsim","de":"A room in a house for entertaining guests; or a small shop","dt":"Misafir ağırlamak için kullanılan oda; veya küçük dükkan","e1":"Beauty parlor.","e1t":"Güzellik salonu.","e2":"Ice cream parlor.","e2t":"Dondurmacı."},{"w":"parody","tr":"parodi / taklit / gülünçleme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of writing or music that copies a style in a funny way","dt":"Bir tarzı komik bir şekilde kopyalayan yazı veya müzik","e1":"A parody of a horror movie.","e1t":"Korku filmi parodisi.","e2":"To parody a famous singer.","e2t":"Ünlü bir şarkıcıyı komik şekilde taklit etmek."},{"w":"parole","tr":"şartlı tahliye / tahliye etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Permission for a prisoner to leave prison before the end of their sentence","dt":"Bir mahkumun ceza süresi bitmeden hapisten çıkma izni","e1":"He was released on parole.","e1t":"Şartlı tahliye ile serbest bırakıldı.","e2":"To eligible for parole.","e2t":"Şartlı tahliyeye hak kazanmak."},{"w":"partial","tr":"kısmi / taraflı /","te":"e meraklı","tt":"Adjective","de":"Sıfat","dt":"Not complete; or supporting one side","e1":"Tam olmayan; veya bir tarafı destekleyen","e1t":"A partial success.","e2":"Kısmi bir başarı.","e2t":"The judge was accused of being partial."},{"w":"particular","tr":"belirli / özel / titiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to one specific person or thing","dt":"Belirli bir kişi veya şeye ilişkin","e1":"In this particular case...","e1t":"Bu özel durumda...","e2":"He is very particular about his food.","e2t":"Yemek konusunda çok titizdir (seçicidir)."},{"w":"partisan","tr":"taraftar / partizan / yandaş","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Strongly supporting one person, principle, or party","dt":"Bir kişiyi, ilkeyi veya partiyi güçlü bir şekilde destekleyen","e1":"A partisan political debate.","e1t":"Taraflı (partizan) bir siyasi tartışma.","e2":"Partisan fighters.","e2t":"Partizan savaşçılar (çeteciler)."},{"w":"pastime","tr":"hobi / eğlence / vakit geçirme","te":"Noun","tt":"İsim","de":"An activity that you enjoy doing in your free time","dt":"Boş zamanlarınızda yapmaktan zevk aldığınız faaliyet","e1":"Reading is my favorite pastime.","e1t":"Kitap okumak en sevdiğim hobimdir.","e2":"National pastime.","e2t":"Ulusal eğlence."},{"w":"pat","tr":"hafifçe vurmak / okşamak","te":"Verb/Noun/Adj/Adv","tt":"To touch someone or something gently with the flat of the hand","de":"Elin içiyle birine veya bir şeye hafifçe dokunmak","dt":"He patted the dog on the head.","e1":"Köpeğin kafasını hafifçe okşadı.","e1t":"A pat on the back.","e2":"Sırt sıvazlama (takdir etme).","e2t":""},{"w":"patent","tr":"patent / tescilli / apaçık","te":"Noun/Verb/Adj","tt":"The legal right to be the only person to make or sell an invention","de":"Bir icadı yapma veya satma hakkına sahip tek kişi olma yasal hakkı","dt":"He applied for a patent for his new invention.","e1":"Yeni icadı için patent başvurusunda bulundu.","e1t":"A patent lie.","e2":"Apaçık bir yalan.","e2t":""},{"w":"paternal","tr":"babaya özgü / baba tarafı","te":"Adjective","tt":"Sıfat","de":"Relating to a father; or inherited from the father's side","dt":"Baba ile ilgili veya baba tarafından gelen","e1":"Paternal instincts.","e1t":"Babalık içigüdüleri.","e2":"My paternal uncle.","e2t":"Amcam (baba tarafındaki amcam)."},{"w":"pathetic","tr":"acınası / zavallı / dokunaklı","te":"Adjective","tt":"Sıfat","de":"Causing feelings of sadness or pity; or very bad","dt":"Üzüntü veya acıma hissi uyandıran; veya çok kötü","e1":"A pathetic cry for help.","e1t":"Acıklı bir yardım çığlığı.","e2":"Your excuse is pathetic.","e2t":"Bahanen zavallıca (çok yetersiz)."},{"w":"pathology","tr":"patoloji / hastalıklar bilimi","te":"Noun","tt":"İsim","de":"The scientific study of diseases","dt":"Hastalıkların bilimsel incelenmesi","e1":"Clinical pathology.","e1t":"Klinik patoloji.","e2":"Speech pathology.","e2t":"Konuşma bozuklukları (patolojisi)."},{"w":"patriarch","tr":"aile reisi (erkek) / patriark","te":"Noun","tt":"İsim","de":"The male head of a family or tribe","dt":"Bir ailenin veya kabilenin erkek başkanı","e1":"The patriarch of the family.","e1t":"Ailenin reisi.","e2":"Patriarchal society.","e2t":"Ataerkil toplum."},{"w":"patron","tr":"müşteri / destekçi / hami","te":"Noun","tt":"İsim","de":"A person who supports an organization or uses a shop","dt":"Bir kuruluşu destekleyen veya bir dükkanı kullanan (müşteri) kişi","e1":"A regular patron of the arts.","e1t":"Sanatın düzenli bir destekçisi.","e2":"The hotel's patrons.","e2t":"Otelin müşterileri."},{"w":"pavilion","tr":"köşk / pavyon / çadır (büyük)","te":"Noun","tt":"İsim","de":"A building used for sports or exhibitions","dt":"Spor veya sergiler için kullanılan bina","e1":"A cricket pavilion.","e1t":"Kriket köşkü.","e2":"The Turkish pavilion at the Expo.","e2t":"Expo'daki Türk pavyonu (sergi alanı)."},{"w":"paw","tr":"pati / pençe / pençelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The foot of an animal that has claws or pads","dt":"Pençeleri veya yastıkları olan hayvan ayağı","e1":"The cat licked its paw.","e1t":"Kedi patisini yaladı.","e2":"Get your paws off me!","e2t":"Ellerini (pençelerini) üzerimden çek!"},{"w":"pawn","tr":"rehin bırakmak / piyon","te":"Noun/Verb","tt":"İsim/Fiil","de":"To leave a possession with someone in order to borrow money; or a chess piece","dt":"Borç almak için bir eşyayı birine bırakmak; veya satranç taşı","e1":"He had to pawn his watch.","e1t":"Saatini rehin bırakmak zorunda kaldı.","e2":"A pawn in a political game.","e2t":"Siyasi bir oyunda piyon."},{"w":"peasant","tr":"köylü / çiftçi (küçük ölçekli)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who owns or rents a small piece of land for farming","dt":"Çiftçilik için küçük bir araziye sahip olan veya kiralayan kişi","e1":"Medieval peasants.","e1t":"Orta Çağ köylüleri.","e2":"Peasant food.","e2t":"Köylü yemeği (sade yemek)."},{"w":"pebble","tr":"çakıl taşı","te":"Noun","tt":"İsim","de":"A small smooth stone found especially on a beach","dt":"Özellikle plajda bulunan küçük düz taş","e1":"The beach was covered with white pebbles.","e1t":"Plaj beyaz çakıl taşlarıyla kaplıydı.","e2":"To throw a pebble into the sea.","e2t":"Denize çakıl taşı atmak."},{"w":"peculiar","tr":"tuhaf / kendine özgü / garip","te":"Adjective","tt":"Sıfat","de":"Strange or unusual; or belonging only to one person","dt":"Garip veya alışılmadık; veya sadece birine/bir şeye ait olan","e1":"A peculiar smell.","e1t":"Tuhaf bir koku.","e2":"A custom peculiar to Turkey.","e2t":"Türkiye'ye özgü bir gelenek."},{"w":"pedal","tr":"pedal / pedal çevirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A lever that you push with your foot to control a machine","dt":"Bir makineyi kontrol etmek için ayakla basılan kol","e1":"Bicycle pedals.","e1t":"Bisiklet pedalları.","e2":"The brake pedal.","e2t":"Fren pedalı."},{"w":"pedigree","tr":"soy ağacı / köken / safkan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The history of an animal's family; or a person's ancestors","dt":"Bir hayvanın aile geçmişi; veya bir kişinin ataları","e1":"A dog with a long pedigree.","e1t":"Uzun bir şeceresi (soy ağacı) olan köpek.","e2":"Pure","e2t":"bred pedigree."},{"w":"peek","tr":"gizlice bakmak / göz atmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look quickly and secretly at something","dt":"Bir şeye hızlıca ve gizlice bakmak","e1":"He peeked through the keyhole.","e1t":"Anahtar deliğinden gizlice baktı.","e2":"To take a peek at the presents.","e2t":"Hediyelere şöyle bir göz atmak."},{"w":"peg","tr":"mandal / çivi / askı / sabitlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small stick or hook used for fastening things","dt":"Bir şeyleri tutturmak için kullanılan küçük çubuk veya kanca","e1":"Clothes peg.","e1t":"Çamaşır mandalı.","e2":"Tent peg.","e2t":"Çadır kazığı."},{"w":"penalize / penalise","tr":"cezalandırmak / dezavantajlı duruma düşürmek","te":"Verb","tt":"Fiil","de":"To punish someone for breaking a rule","dt":"Bir kuralı çiğnediği için birini cezalandırmak","e1":"The player was penalized for a foul.","e1t":"Oyuncu faul yaptığı için cezalandırıldı.","e2":"The new tax penalizes low","e2t":"income families."},{"w":"pendant","tr":"kolye ucu / sarkaç","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A piece of jewelry that hangs from a chain around the neck","dt":"Boyna takılan bir zincirden sarkan mücevher parçası","e1":"A gold pendant.","e1t":"Altın kolye ucu.","e2":"Diamond pendant.","e2t":"Elmas kolye ucu."},{"w":"pending","tr":"askıda / beklemede /","te":"e kadar","tt":"Adjective/Preposition","de":"Waiting to be decided or dealt with; or until","dt":"Karara bağlanmayı veya ilgilenilmeyi bekleyen; veya ... olana kadar","e1":"The decision is still pending.","e1t":"Karar hala beklemede (askıda).","e2":"Pending the results of the investigation.","e2t":"Soruşturma sonuçları belli olana kadar."},{"w":"pensive","tr":"düşünceli / dalgın / mahzun","te":"Adjective","tt":"Sıfat","de":"Thinking deeply and quietly, often about something sad","dt":"Genellikle üzücü bir şey hakkında derin ve sessizce düşünen","e1":"She looked pensive as she stared out the window.","e1t":"Pencereden dışarı bakarken düşünceli görünüyordu.","e2":"In a pensive mood.","e2t":"Düşünceli bir ruh halinde."},{"w":"perch","tr":"tünemek / yüksekçe yer / tüneme yeri","te":"Verb/Noun","tt":"Fiil/İsim","de":"To sit on the edge of something; or a place for a bird to sit","dt":"Bir şeyin kenarına oturmak; veya kuşun tüneme yeri","e1":"A bird perched on the branch.","e1t":"Bir kuş dala tünedi.","e2":"He perched on the edge of the table.","e2t":"Masanın kenarına ilişti (oturdu)."},{"w":"perennial","tr":"uzun ömürlü / kalıcı / çok yıllık (bitki)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Lasting for a long time or happening repeatedly","dt":"Uzun süre devam eden veya tekrar tekrar gerçekleşen","e1":"A perennial problem.","e1t":"Bitmek bilmeyen (kalıcı) bir sorun.","e2":"Perennial plants.","e2t":"Çok yıllık bitkiler."},{"w":"perimeter","tr":"çevre / dış hatlar","te":"Noun","tt":"İsim","de":"The outer edge of an area or shape","dt":"Bir alanın veya şeklin dış kenarı","e1":"The perimeter of the football field.","e1t":"Futbol sahasının çevresi.","e2":"Guards patrolled the perimeter.","e2t":"Muhafızlar dış hattı (çevreyi) kontrol etti."},{"w":"periodical","tr":"süreli yayın / dergi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A magazine that is published every week or month","dt":"Her hafta veya ay yayınlanan dergi","e1":"Academic periodicals.","e1t":"Akademik süreli yayınlar.","e2":"Periodical visits.","e2t":"Periyodik (belirli aralıklarla yapılan) ziyaretler."},{"w":"perish","tr":"yok olmak / can vermek / çürümek","te":"Verb","tt":"Fiil","de":"To die, especially in a sudden or violent way","dt":"Özellikle ani veya şiddetli bir şekilde ölmek","e1":"Thousands of people perished in the earthquake.","e1t":"Depremde binlerce kişi can verdi (yok oldu).","e2":"Perishable goods (food that decays quickly).","e2t":"Çabuk bozulan (çürüyen) ürünler."},{"w":"perjury","tr":"yalancı şahitlik / yalan yere yemin","te":"Noun","tt":"İsim","de":"The crime of telling a lie in court after promising to tell the truth","dt":"Mahkemede doğruyu söyleyeceğine yemin ettikten sonra yalan söyleme suçu","e1":"He was found guilty of perjury.","e1t":"Yalancı şahitlikten suçlu bulundu.","e2":"To commit perjury.","e2t":"Yalan yere yemin etmek."},{"w":"permeate","tr":"içine işlemek / her yanına yayılmak / nüfuz etmek","te":"Verb","tt":"Fiil","de":"To spread through every part of something","dt":"Bir şeyin her parçasına yayılmak","e1":"The smell of coffee permeated the house.","e1t":"Kahve kokusu evin her yanına yayıldı.","e2":"Political corruption permeates the system.","e2t":"Siyasi yolsuzluk sisteme nüfuz etmiş (işlemiş)."},{"w":"permissive","tr":"hoşgörülü / tavizkar / serbestçi","te":"Adjective","tt":"Sıfat","de":"Allowing a lot of freedom, especially in sexual behavior","dt":"Özellikle cinsel davranışlarda büyük özgürlük tanıyan","e1":"Permissive parents.","e1t":"Hoşgörülü (gevşek) ebeveynler.","e2":"A permissive society.","e2t":"Serbestçi bir toplum."},{"w":"perpendicular","tr":"dik / dikey","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"At an angle of 90 degrees to a surface","dt":"Bir yüzeye 90 derecelik açıyla duran","e1":"The wall is perpendicular to the floor.","e1t":"Duvar zemine diktir.","e2":"To draw a perpendicular line.","e2t":"Dik bir çizgi çizmek."},{"w":"perpetrate","tr":"(suç) işlemek / yapmak","te":"Verb","tt":"Fiil","de":"To commit a crime or a violent act","dt":"Bir suç veya şiddet eylemi işlemek","e1":"To perpetrate a fraud.","e1t":"Dolandırıcılık yapmak.","e2":"Terrible crimes were perpetrated during the war.","e2t":"Savaş sırasında korkunç suçlar işlendi."},{"w":"perplex","tr":"kafasını karıştırmak / şaşırtmak","te":"Verb","tt":"Fiil","de":"To confuse someone very much","dt":"Birinin kafasını çok karıştırmak","e1":"The complicated instructions perplexed me.","e1t":"Karmaşık talimatlar kafamı çok karıştırdı.","e2":"A perplexing problem.","e2t":"Kafa karıştırıcı bir sorun."},{"w":"persecute","tr":"zulmetmek / eziyet etmek","te":"Verb","tt":"Fiil","de":"To treat someone unfairly because of their beliefs","dt":"İnançlarından dolayı birine adaletsiz davranmak","e1":"They were persecuted for their religion.","e1t":"Dinlerinden dolayı zulüm gördüler.","e2":"To feel persecuted.","e2t":"Eziyet görmüş (baskı altında) hissetmek."},{"w":"persevere","tr":"sebat etmek / yılmamak / azmetmek","te":"Verb","tt":"Fiil","de":"To continue trying to do something despite difficulties","dt":"Zorluklara rağmen bir şeyi yapmaya devam etmek","e1":"You must persevere if you want to succeed.","e1t":"Başarmak istiyorsan azmetmelisin (yılmamalısın).","e2":"To persevere with one's studies.","e2t":"Çalışmalarına sebatla devam etmek."},{"w":"perspire","tr":"terlemek","te":"Verb","tt":"Fiil","de":"To sweat","dt":"Terlemek (resmi ifade)","e1":"He began to perspire in the heat.","e1t":"Sıcakta terlemeye başladı.","e2":"Perspiration (sweat).","e2t":"Ter (terleme)."},{"w":"pertinent","tr":"ilgili / yerinde / münasip","te":"Adjective","tt":"Sıfat","de":"Relating directly to the subject being discussed","dt":"Tartışılan konuyla doğrudan ilgili olan","e1":"A pertinent question.","e1t":"Yerinde (ilgili) bir soru.","e2":"Please provide all pertinent information.","e2t":"Lütfen konuyla ilgili tüm bilgileri sağlayın."},{"w":"pervasive","tr":"yaygın / her tarafa sinmiş","te":"Adjective","tt":"Sıfat","de":"Present or noticeable in every part of something","dt":"Bir şeyin her parçasında mevcut veya fark edilir olan","e1":"The pervasive influence of social media.","e1t":"Sosyal medyanın yaygın etkisi.","e2":"A pervasive smell of damp.","e2t":"Her tarafa sinmiş rutubet kokusu."},{"w":"pessimism","tr":"kötümserlik / karamsarlık","te":"Noun","tt":"İsim","de":"A feeling that bad things will happen","dt":"Kötü şeylerin olacağına dair his","e1":"There is a mood of deep pessimism in the company.","e1t":"Şirkette derin bir kötümserlik havası var.","e2":"To overcome your pessimism.","e2t":"Karamsarlığını yenmek."},{"w":"petty","tr":"önemsiz / küçük / değersiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Small and not important","dt":"Küçük ve önemli olmayan","e1":"Petty theft.","e1t":"Küçük çaplı hırsızlık.","e2":"Don't waste time on petty details.","e2t":"Önemsiz detaylarla vakit kaybetme."},{"w":"philanthropy","tr":"hayırseverlik / insanseverlik","te":"Noun","tt":"İsim","de":"The practice of helping poor people by giving money","dt":"Fakir insanlara para vererek yardım etme uygulaması","e1":"He is known for his philanthropy.","e1t":"Hayırseverliği ile tanınır.","e2":"Philanthropic organizations.","e2t":"Hayır kurumları."},{"w":"philosopher","tr":"filozof / felsefeci","te":"Noun","tt":"İsim","de":"A person who studies or writes about philosophy","dt":"Felsefe üzerine çalışan veya yazan kişi","e1":"Plato was a great Greek philosopher.","e1t":"Platon büyük bir Yunan filozofuydu.","e2":"Moral philosopher.","e2t":"Ahlak filozofu."},{"w":"phony / phoney","tr":"sahte / yapmacık / düzmece","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not real or sincere","dt":"Gerçek veya samimi olmayan","e1":"A phony accent.","e1t":"Yapmacık bir aksan.","e2":"He is a complete phony.","e2t":"O tamamen sahtekar (yapmacık) biridir."},{"w":"physique","tr":"vücut yapısı / fizik","te":"Noun","tt":"İsim","de":"The shape and size of a human body","dt":"İnsan vücudunun şekli ve boyutu","e1":"He has a powerful physique.","e1t":"Güçlü bir vücut yapısı (fiziği) var.","e2":"To improve your physique.","e2t":"Fiziğini geliştirmek."},{"w":"picturesque","tr":"resmedilmeye değer / çok güzel / otantik","te":"Adjective","tt":"Sıfat","de":"(Of a place) attractive in an old","dt":"fashioned way","e1":"(Yer için) eski moda ve çekici (kartpostal gibi)","e1t":"A picturesque village.","e2":"Resmedilmeye değer (çok güzel) bir köy.","e2t":"Picturesque scenery."},{"w":"pier","tr":"iskele / rıhtım / ayak (köprü)","te":"Noun","tt":"İsim","de":"A structure built out into the sea for people to walk on","dt":"İnsanların üzerinde yürümesi için denize doğru inşa edilmiş yapı","e1":"We walked along the pier.","e1t":"İskele boyunca yürüdük.","e2":"Pier pressure (pun","e2t":"peer pressure)."},{"w":"piety","tr":"dindarlık / saygı (dini)","te":"Noun","tt":"Isim","de":"Strong belief in a religion","dt":"Bir dine duyulan güçlü inanç","e1":"A life of piety and prayer.","e1t":"Dindarlık ve dua ile dolu bir yaşam.","e2":"Filial piety (respect for parents).","e2t":"Evlatlık görevi (ebeveyne saygı)."},{"w":"pigeon","tr":"güvercin","te":"Noun/Verb","tt":"İsim/Fiil","de":"A common grey bird that lives in cities","dt":"Şehirlerde yaşayan yaygın gri kuş","e1":"To feed the pigeons in the square.","e1t":"Meydandaki güvercinleri beslemek.","e2":"Carrier pigeon.","e2t":"Posta güvercini."},{"w":"pilgrim","tr":"hacı / yolcu (dini)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who travels to a holy place for religious reasons","dt":"Dini nedenlerle kutsal bir yere seyahat eden kişi","e1":"Muslim pilgrims going to Mecca.","e1t":"Mekke'ye giden Müslüman hacılar.","e2":"Pilgrim Fathers.","e2t":"Hacı Babalar (ABD tarihinden)."},{"w":"pillar","tr":"sütun / direk / temel direği","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tall stone post used to support a building","dt":"Bir binayı desteklemek için kullanılan uzun taş direk","e1":"The five pillars of Islam.","e1t":"İslam'ın beş şartı (temel direği).","e2":"He is a pillar of the community.","e2t":"O, toplumun temel direklerinden (saygın üyelerinden) biridir."},{"w":"pin","tr":"iğne / toplu iğne / pim / takmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small thin piece of metal; or to fasten","dt":"Küçük ince metal parça; veya tutturmak","e1":"Safety pin.","e1t":"Çengelli iğne.","e2":"Rolling pin.","e2t":"Oklava."},{"w":"pious","tr":"dindar / ibadetine düşkün","te":"Adjective","tt":"Sıfat","de":"Strongly believing in religion and living by its rules","dt":"Dine güçlü bir şekilde inanan ve kurallarına göre yaşayan","e1":"A pious man who never missed a prayer.","e1t":"Hiçbir namazı kaçırmayan dindar bir adam.","e2":"Pious hopes (unrealistic).","e2t":"Boş umutlar (gerçekleşmesi zor temenniler)."},{"w":"pistol","tr":"tabanca","te":"Noun","tt":"İsim","de":"A small gun that is held in one hand","dt":"Tek elle tutulan küçük silah","e1":"The criminal was carrying a loaded pistol.","e1t":"Suçlu, dolu bir tabanca taşıyordu.","e2":"Automatic pistol.","e2t":"Otomatik tabanca."},{"w":"pit","tr":"çukur / maden ocağı / çekirdek (meyve)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large hole in the ground; or the stone in a fruit","dt":"Yer altındaki büyük delik; veya meyve çekirdeği","e1":"The miners worked deep in the pit.","e1t":"Madenciler ocağın derinliklerinde çalıştı.","e2":"To remove the pits from the cherries.","e2t":"Vişnelerin çekirdeklerini çıkarmak."},{"w":"pitfall","tr":"tuzak / gizli tehlike / beklenmedik güçlük","te":"Noun","tt":"İsim","de":"A hidden danger or difficulty","dt":"Gizli bir tehlike veya zorluk","e1":"To avoid the common pitfalls of learning a language.","e1t":"Dil öğrenmenin yaygın tuzaklarından (hatalarından) kaçınmak.","e2":"Financial pitfalls.","e2t":"Finansal tuzaklar."},{"w":"pivot","tr":"dönme noktası / eksen / kilit isim","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fixed point on which something turns; or a key person","dt":"Bir şeyin üzerinde döndüğü sabit nokta; veya kilit kişi","e1":"He is the pivot of the whole team.","e1t":"O tüm takımın kilit ismidir (merkezidir).","e2":"The door turns on a pivot.","e2t":"Kapı bir mil (eksen) üzerinde döner."},{"w":"placard","tr":"döviz / pankart / afiş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large piece of card with a message used in protests","dt":"Protestolarda kullanılan mesaj içerikli büyük karton","e1":"Protesters carried placards with slogans.","e1t":"Protestocular slogan yazılı pankartlar taşıdı.","e2":"To placard the walls.","e2t":"Duvarlara afiş asmak."},{"w":"plaintiff","tr":"davacı / şikayetçi","te":"Noun","tt":"İsim","de":"A person who brings a case against another in a court","dt":"Mahkemede başkasına dava açan kişi","e1":"The plaintiff is seeking damages for the accident.","e1t":"Davacı, kaza için tazminat istiyor.","e2":"Counsel for the plaintiff.","e2t":"Davacı vekili."},{"w":"plaque","tr":"plaket / diş taşı / levha","te":"Noun","tt":"İsim","de":"A flat piece of metal or stone with writing; or on teeth","dt":"Üzerinde yazı olan düz metal/taş; veya dişlerdeki tabaka","e1":"A commemorative plaque on the wall.","e1t":"Duvarda bir anma levhası.","e2":"Brushing your teeth removes plaque.","e2t":"Diş fırçalamak diş taşlarını (plakları) temizler."},{"w":"plasma","tr":"plazma","te":"Noun","tt":"İsim","de":"The pale yellow liquid part of the blood; or a state of matter","dt":"Kanın sarımtırak sıvı kısmı; veya maddenin bir hali","e1":"Blood plasma.","e1t":"Kan plazması.","e2":"Plasma TV.","e2t":"Plazma TV."},{"w":"plateau","tr":"plato / yayla / duraksama dönemi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large area of high flat land; or a period of no growth","dt":"Yüksek düzlük alan; veya büyümenin durduğu dönem","e1":"The Anatolian plateau.","e1t":"Anadolu platosu.","e2":"My English progress has reached a plateau.","e2t":"İngilizce gelişimim bir duraksama dönemine (platoya) girdi."},{"w":"platinum","tr":"platin","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very valuable silver","dt":"white metal","e1":"Çok değerli gümüş","e1t":"beyaz metal","e2":"A platinum wedding ring.","e2t":"Platin alyans."},{"w":"plausible","tr":"makul / akla yakın / inanılabilir","te":"Adjective","tt":"Sıfat","de":"Seeming likely to be true or able to be believed","dt":"Doğru görünmesi muhtemel veya inanılabilir olan","e1":"A plausible explanation.","e1t":"Makul (akla yakın) bir açıklama.","e2":"It sounds plausible.","e2t":"Kulağa mantıklı geliyor."},{"w":"playwright","tr":"oyun yazarı","te":"Noun","tt":"İsim","de":"A person who writes plays","dt":"Tiyatro oyunu yazan kişi","e1":"Shakespeare is the most famous playwright in history.","e1t":"Shakespeare tarihteki en ünlü oyun yazarıdır.","e2":"Contemporary playwright.","e2t":"Çağdaş oyun yazarı."},{"w":"plea","tr":"yalvarış / savunma / mazeret","te":"Noun","tt":"Isim","de":"An urgent and emotional request; or a statement in court","dt":"Acil ve duygusal istek; veya mahkemedeki ifade/savunma","e1":"A desperate plea for help.","e1t":"Çaresiz bir yardım çığlığı (yalvarışı).","e2":"A plea of not guilty.","e2t":"Suçsuzluk savunması."},{"w":"plight","tr":"zor durum / hazin vaziyet","te":"Noun","tt":"İsim","de":"An unpleasant or difficult situation","dt":"Nahoş veya zor durum","e1":"The plight of the refugees.","e1t":"Mültecilerin hazin durumu (çilesi).","e2":"To understand their plight.","e2t":"Onların zor durumunu anlamak."},{"w":"plow / plough","tr":"sabanla sürmek / kar küreği / saban","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large farming tool to turn soil; or to clear snow","dt":"Toprağı çevirmek için kullanılan tarım aleti; veya kar temizlemek","e1":"The farmer is plowing the field.","e1t":"Çiftçi tarlayı sürüyor.","e2":"A snow plow.","e2t":"Kar küreme aracı."},{"w":"pluck","tr":"koparmak / yolmak / telli çalgı çalmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull something quickly; or to remove feathers","dt":"Bir şeyi hızla çekmek; veya tüyleri yolmak","e1":"She plucked a flower from the garden.","e1t":"Bahçeden bir çiçek koptu.","e2":"To pluck the strings of a guitar.","e2t":"Gitarın tellerini çekmek (çalmak)."},{"w":"plum","tr":"erik / çok arzu edilen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A small round fruit with purple or yellow skin","dt":"Mor veya sarı kabuklu küçük yuvarlak meyve","e1":"Dried plums (prunes).","e1t":"Kuru erik.","e2":"A plum job.","e2t":"Çok arzu edilen (yağlı) bir iş."},{"w":"plus","tr":"artı / avantaj","te":"Prep/Adj/Noun","tt":"Added to; or an advantage","de":"Eklenmiş; veya avantaj","dt":"Two plus two is four.","e1":"İki artı iki dörttür.","e1t":"A salary of $5000 plus bonuses.","e2":"5000 dolar maaş artı primler.","e2t":""},{"w":"pneumonia","tr":"zatürre","te":"Noun","tt":"İsim","de":"A serious illness of the lungs","dt":"Akciğerlerin ciddi bir hastalığı","e1":"He was hospitalized with pneumonia.","e1t":"Zatürre nedeniyle hastaneye yatırıldı.","e2":"Symptoms of pneumonia.","e2t":"Zatürre belirtileri."},{"w":"pod","tr":"kapsül / koza / (balina vb.) sürü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long narrow container for seeds; or a group of whales","dt":"Tohumlar için uzun dar kap; veya balina grubu","e1":"Pea pods.","e1t":"Bezelye kapsülleri.","e2":"A pod of dolphins.","e2t":"Yunus sürüsü."},{"w":"poignant","tr":"dokunaklı / hüzünlü / içe işleyen","te":"Adjective","tt":"Sıfat","de":"Causing a strong feeling of sadness","dt":"Güçlü bir üzüntü hissi uyandıran","e1":"A poignant movie about war.","e1t":"Savaş hakkında dokunaklı bir film.","e2":"Poignant memories.","e2t":"Hüzünlü anılar."},{"w":"poise","tr":"denge / duruş / özgüven","te":"Noun/Verb","tt":"İsim/Fiil","de":"A calm, confident manner; or balance","dt":"Sakin ve özgüvenli tavır; veya denge","e1":"She showed great poise during the interview.","e1t":"Mülakat sırasında büyük bir vakar (özgüvenli duruş) sergiledi.","e2":"To lose your poise.","e2t":"Soğukkanlılığını kaybetmek."},{"w":"polar","tr":"kutupsal / zıt","te":"Adjective","tt":"Sıfat","de":"Relating to the North or South Pole; or complete opposites","dt":"Kuzey veya Güney Kutbu ile ilgili; veya tam zıt","e1":"Polar bear.","e1t":"Kutup ayısı.","e2":"Their views are polar opposites.","e2t":"Görüşleri birbirine tamamen zıttır."},{"w":"pollen","tr":"polen / çiçek tozu","te":"Noun","tt":"İsim","de":"A powder produced by flowers to make seeds","dt":"Çiçeklerin tohum yapmak için ürettiği toz","e1":"Beeson collect pollen.","e1t":"Arılar polen toplar.","e2":"Pollen allergy.","e2t":"Polen alerjisi."},{"w":"pollute","tr":"kirletmek","te":"Verb","tt":"Fiil","de":"To make air, water, or land dirty and dangerous","dt":"Havayı, suyu veya toprağı kirli ve tehlikeli hale getirmek","e1":"Factories pollute the river with chemicals.","e1t":"Fabrikalar nehri kimyasallarla kirletiyor.","e2":"To pollute the atmosphere.","e2t":"Atmosferi kirletmek."},{"w":"ponder","tr":"üzerinde düşünmek / kafa yormak","te":"Verb","tt":"Fiil","de":"To think carefully about something for a long time","dt":"Bir şey üzerinde uzun süre dikkatle düşünmek","e1":"He sat alone, pondering his future.","e1t":"Tek başına oturup geleceği üzerine kafa yordu.","e2":"To ponder a question.","e2t":"Bir soru üzerinde düşünmek."},{"w":"porcelain","tr":"porselen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard white substance used for making plates and cups","dt":"Tabak ve fincan yapımında kullanılan sert beyaz madde","e1":"A delicate porcelain vase.","e1t":"Zarif bir porselen vazo.","e2":"Porcelain doll.","e2t":"Porselen bebek."},{"w":"pore","tr":"gözenek / dikkatle incelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very small hole in the skin; or to study carefully","dt":"Ciltteki çok küçük delik; veya dikkatle çalışmak","e1":"Sweat comes out through the pores.","e1t":"Ter, gözeneklerden dışarı çıkar.","e2":"To pore over a map.","e2t":"Bir haritayı dikkatle incelemek."},{"w":"port","tr":"liman / iskele tarafı / giriş (bilgisayar)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A town by the sea with a harbor; or the left side of a ship","dt":"Limanı olan deniz kıyısı kasabası; veya geminin sol tarafı","e1":"Istanbul is a major port.","e1t":"İstanbul önemli bir limandır.","e2":"USB port.","e2t":"USB girişi."},{"w":"porter","tr":"hamal / kapıcı (otel/hastane)","te":"Noun","tt":"İsim","de":"A person whose job is to carry luggage","dt":"İşi bagaj taşımak olan kişi","e1":"The hotel porter took our bags.","e1t":"Otel hamalı (görevlisi) çantalarımızı aldı.","e2":"Hospital porter.","e2t":"Hastane hasta bakıcısı/taşıyıcısı."},{"w":"portfolio","tr":"portföy / dosya","te":"Noun","tt":"İsim","de":"A collection of work; or a range of investments","dt":"Yapılan işlerin koleksiyonu; veya yatırım yelpazesi","e1":"An artist's portfolio.","e1t":"Bir sanatçının portföyü (çalışma dosyası).","e2":"To manage a stock portfolio.","e2t":"Hisse senedi portföyünü yönetmek."},{"w":"portray","tr":"betimlemek / canlandırmak / yansıtmak","te":"Verb","tt":"Fiil","de":"To describe or show someone in a particular way","dt":"Birini belirli bir şekilde göstermek veya anlatmak","e1":"The book portrays him as a hero.","e1t":"Kitap onu bir kahraman olarak yansıtıyor.","e2":"She portrays the main character in the play.","e2t":"Oyunda ana karakteri canlandırıyor."},{"w":"postage","tr":"posta ücreti","te":"Noun","tt":"Isim","de":"The money that you pay to send a letter","dt":"Mektup göndermek için ödenen para","e1":"How much is the postage for this parcel?","e1t":"Bu paketin posta ücreti ne kadar?","e2":"Postage stamp.","e2t":"Posta pulu."},{"w":"posterity","tr":"gelecek nesiller / gelecek kuşaklar","te":"Noun","tt":"İsim","de":"The people who will exist in the future","dt":"Gelecekte var olacak insanlar","e1":"The building should be preserved for posterity.","e1t":"Bina gelecek kuşaklar için korunmalıdır.","e2":"To record a story for posterity.","e2t":"Bir hikayeyi gelecek nesiller için kaydetmek."},{"w":"pot","tr":"tencere / saksı / çömlek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A round container used for cooking or keeping plants","dt":"Yemek pişirmek veya bitki bakmak için kullanılan yuvarlak kap","e1":"A cooking pot.","e1t":"Yemek tenceresi.","e2":"Flower pot.","e2t":"Çiçek saksısı."},{"w":"potent","tr":"güçlü / etkili","te":"Adjective","tt":"Sıfat","de":"Very powerful or effective","dt":"Çok güçlü veya etkili","e1":"A potent drug.","e1t":"Güçlü (etkili) bir ilaç.","e2":"A potent symbol of freedom.","e2t":"Özgürlüğün güçlü bir simgesi."},{"w":"poultry","tr":"kümes hayvanları","te":"Noun","tt":"İsim","de":"Birds such as chickens that are kept for meat or eggs","dt":"Et veya yumurta için bakılan tavuk gibi kuşlar","e1":"They keep poultry on the farm.","e1t":"Çiftlikte kümes hayvanı besliyorlar.","e2":"Poultry farm.","e2t":"Tavuk çiftliği."},{"w":"pounce","tr":"üzerine atılmak / pençelemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To jump quickly in order to catch something","dt":"Bir şeyi yakalamak için hızla üzerine atlamak","e1":"The cat was waiting to pounce on the mouse.","e1t":"Kedi farenin üzerine atılmak için bekliyordu.","e2":"To pounce on an opportunity.","e2t":"Bir fırsatın üzerine atlamak."},{"w":"pour","tr":"dökmek / akmak / boşaltmak","te":"Verb","tt":"Fiil","de":"To make a liquid flow from a container","dt":"Bir sıvının kaptan akmasını sağlamak","e1":"Please pour me some water.","e1t":"Lütfen bana biraz su doldur (dök).","e2":"It’s pouring with rain (raining hard).","e2t":"Bardaktan boşalırcasına yağmur yağıyor."},{"w":"prairie","tr":"çayır / bozkır / büyük ova","te":"Noun","tt":"İsim","de":"A large area of flat land with grass and few trees","dt":"Az ağaçlı, çimenlik geniş düzlük alan","e1":"The vast prairies of North America.","e1t":"Kuzey Amerika'nın uçsuz buçsız bozkırları (çayırları).","e2":"Prairie fire.","e2t":"Bozkır yangını."},{"w":"precarious","tr":"istikrarsız / tehlikeli / eğreti","te":"Adjective","tt":"Sıfat","de":"In a dangerous state because it is not safe or certain","dt":"Güvenli veya kesin olmadığı için tehlikeli durumda olan","e1":"The ladder looked very precarious.","e1t":"Merdiven çok eğreti (tehlikeli) görünüyordu.","e2":"A precarious financial situation.","e2t":"İstikrarsız bir finansal durum."},{"w":"precedent","tr":"emsal / örnek / geçmiş örnek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An action that is used as an example for the future","dt":"Gelecek için örnek olarak kullanılan eylem","e1":"This decision sets a precedent for future cases.","e1t":"Bu karar gelecekteki davalar için bir emsal teşkil eder.","e2":"Without precedent (unprecedented).","e2t":"Emsalsiz."},{"w":"precipitate","tr":"hızlandırmak / yağış / aceleci","te":"Verb/Noun/Adj","tt":"To make something happen sooner; or rain/snow","de":"Bir şeyin daha erken olmasını sağlamak; veya yağış","dt":"The crisis was precipitated by a sudden rise in prices.","e1":"Kriz, fiyatlardaki ani yükselişle hızlandı (tetiklendi).","e1t":"Annual precipitation (rain).","e2":"Yıllık yağış miktarı.","e2t":""},{"w":"predator","tr":"yırtıcı / avcı","te":"Noun","tt":"İsim","de":"An animal that hunts and eats other animals","dt":"Diğer hayvanları avlayan ve yiyen hayvan","e1":"Lions are top predators.","e1t":"Aslanlar en üst düzey avcılardır (yırtıcılardır).","e2":"Online predators (dangerous people).","e2t":"İnternet ortamındaki saldırganlar."},{"w":"predecessor","tr":"selef / öncel / bir önceki görevli","te":"Noun","tt":"İsim","de":"The person who had a job before the current person","dt":"Mevcut kişiden önce o işte çalışan kişi","e1":"My predecessor was much more organized than I am.","e1t":"Benden önceki görevli (selefim) benden çok daha düzenliydi.","e2":"The new model is better than its predecessor.","e2t":"Yeni model bir önceki örneğinden (selefinden) daha iyi."},{"w":"predicament","tr":"açmaz / zor durum / müşkilat","te":"Noun","tt":"İsim","de":"A difficult or unpleasant situation","dt":"Zor veya nahoş durum","e1":"I'm in a bit of a predicament.","e1t":"Biraz zor bir durumdayım (açmazdayım).","e2":"How to get out of this predicament?","e2t":"Bu açmazdan nasıl çıkılır?"},{"w":"preface","tr":"önsöz / giriş yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An introduction to a book or speech","dt":"Kitap veya konuşmanın giriş kısmı","e1":"He wrote a preface to his new book.","e1t":"Yeni kitabına bir önsöz yazdı.","e2":"To preface a remark with an apology.","e2t":"Söze bir özürle başlamak (giriş yapmak)."},{"w":"prefix","tr":"önek / alan kodu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A letter or group of letters added to the start of a word","dt":"Bir kelimenin başına eklenen harf grubu","e1":"\"Un","e1t":"\" is a common prefix.","e2":"\"Un","e2t":"\" yaygın bir önektir."},{"w":"premature","tr":"erken / vaktinden önce","te":"Adjective","tt":"Sıfat","de":"Happening before the normal or expected time","dt":"Normal veya beklenen zamandan önce olan","e1":"A premature baby.","e1t":"Prematüre (erken doğmuş) bebek.","e2":"It is premature to reach a conclusion.","e2t":"Bir sonuca varmak için henüz erkendir."},{"w":"premier","tr":"başbakan / birinci / ilk","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The leader of a government; or best/most important","dt":"Hükümet başkanı; veya en iyi/önemli","e1":"The Premier of Ontario.","e1t":"Ontario Başbakanı.","e2":"One of the country’s premier hotels.","e2t":"Ülkenin önde gelen (en iyi) otellerinden biri."},{"w":"premise","tr":"öncül / dayanak / mülk","te":"Noun/Verb","tt":"İsim/Fiil","de":"An idea that you use to support an argument; or a building","dt":"Bir iddiayı destekleyen fikir; veya bina/mülk","e1":"The conclusion is based on a false premise.","e1t":"Sonuç yanlış bir öncüle dayanıyor.","e2":"Business premises.","e2t":"İşletme mülkü (binası)."},{"w":"premium","tr":"prim / üst düzey / kasko bedeli","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An amount of money paid for insurance; or high quality","dt":"Sigorta için ödenen miktar; veya yüksek kaliteli","e1":"Monthly insurance premiums.","e1t":"Aylık sigorta primleri.","e2":"Premium quality coffee.","e2t":"Üstün kaliteli kahve."},{"w":"preoccupation","tr":"zihni meşgul etme / saplantı / uğraş","te":"Noun","tt":"İsim","de":"A state of thinking about something constantly","dt":"Bir şeyi sürekli düşünme durumu","e1":"His main preoccupation is his health.","e1t":"Onu en çok meşgul eden şey (saplantısı) sağlığıdır.","e2":"Career preoccupation.","e2t":"Kariyer telaşı."},{"w":"preposition","tr":"edat / ilgeç","te":"Noun","tt":"İsim","de":"A word that shows the relationship between a noun and another word","dt":"Bir isim ile diğer kelime arasındaki ilişkiyi gösteren kelime","e1":"\"In\", \"on\", and \"at\" are prepositions.","e1t":"\"In\", \"on\" ve \"at\" edattır.","e2":"Prepositional phrase.","e2t":"Edat öbeği."},{"w":"preposterous","tr":"saçma / akıl dışı / absürt","te":"Adjective","tt":"Sıfat","de":"Completely unreasonable or silly","dt":"Tamamen mantıksız veya aptalca","e1":"A preposterous suggestion.","e1t":"Saçma bir öneri.","e2":"That's preposterous!","e2t":"Bu akıl dışı (saçma)!"},{"w":"prerogative","tr":"ayrıcalık / imtiyaz","te":"Noun","tt":"İsim","de":"A special right that a particular person has","dt":"Belirli bir kişinin sahip olduğu özel hak","e1":"It is the manager’s prerogative to hire staff.","e1t":"Personel işe almak müdürün imtiyazıdır (hakkıdır).","e2":"Royal prerogative.","e2t":"Kraliyet ayrıcalığı."},{"w":"preside","tr":"başkanlık etmek / yönetmek","te":"Verb","tt":"Fiil","de":"To be in charge of a formal meeting or event","dt":"Resmi bir toplantı veya etkinliğin başında olmak","e1":"The judge presided over the trial.","e1t":"Davaya yargıç başkanlık etti.","e2":"To preside at a meeting.","e2t":"Toplantıyı yönetmek."},{"w":"prestige","tr":"prestij / itibar / saygınlık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Respect and admiration given to someone important","dt":"Önemli birine duyulan saygı ve hayranlık","e1":"To win a award of great prestige.","e1t":"Çok prestijli bir ödül kazanmak.","e2":"Professional prestige.","e2t":"Mesleki itibar."},{"w":"presume","tr":"varsaymak / tahmin etmek / cüret etmek","te":"Verb","tt":"Fiil","de":"To think that something is likely to be true","dt":"Bir şeyin muhtemelen doğru olduğunu düşünmek","e1":"I presume that you are tired after the journey.","e1t":"Yolculuktan sonra yorgun olduğunuzu varsayıyorum.","e2":"Presumed dead.","e2t":"Öldüğü varsayılan."},{"w":"pretext","tr":"bahane / uydurma sebep","te":"Noun","tt":"İsim","de":"A false reason given to hide the real one","dt":"Gerçek sebebi gizlemek için verilen uydurma neden","e1":"He left the room on the pretext of making a phone call.","e1t":"Telefon etme bahanesiyle odadan çıktı.","e2":"Under the pretext of...","e2t":"... bahanesiyle."},{"w":"prevail","tr":"hakim olmak / galip gelmek / yaygın olmak","te":"Verb","tt":"Fiil","de":"To be common among a group; or to defeat an opponent","dt":"Bir grup arasında yaygın olmak; veya rakibi yenmek","e1":"Justice will prevail.","e1t":"Adalet yerini bulacak (galip gelecek).","e2":"The custom still prevails in some villages.","e2t":"Bu gelenek bazı köylerde hala hakimdir (devam eder)."},{"w":"prevalent","tr":"yaygın / genel","te":"Adjective","tt":"Sıfat","de":"Existing very commonly or happening often","dt":"Çok yaygın olan veya sık gerçekleşen","e1":"The disease is more prevalent in children.","e1t":"Hastalık çocuklarda daha yaygındır.","e2":"Prevalent beliefs.","e2t":"Yaygın inançlar."},{"w":"prick","tr":"batırmak / delmek / sızı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a very small hole with a sharp point","dt":"Keskin bir uçla çok küçük bir delik açmak","e1":"I pricked my finger with a needle.","e1t":"Parmağıma iğne battı (batırdım).","e2":"To prick a balloon.","e2t":"Bir balonu delmek."},{"w":"prince","tr":"prens / hükümdar","te":"Noun","tt":"İsim","de":"The son of a king or queen","dt":"Kral veya kraliçenin oğlu","e1":"Prince Charles.","e1t":"Prens Charles.","e2":"A merchant prince (powerful businessman).","e2t":"Ticaret beyi (nüfuzlu iş adamı)."},{"w":"probation","tr":"denetimli serbestlik / deneme süresi","te":"Noun","tt":"İsim","de":"A period of time when a criminal or new worker is watched","dt":"Bir suçlunun veya yeni çalışanın izlendiği süre","e1":"He was put on probation for two years.","e1t":"İki yıl denetimli serbestliğe tabi tutuldu.","e2":"Three","e2t":"month probation period."},{"w":"procrastinate","tr":"ertelemek (üşengeçlikten) / savsaklamak","te":"Verb","tt":"Fiil","de":"To delay doing something that you should do","dt":"Yapmanız gereken bir şeyi yapmayı geciktirmek","e1":"Stop procrastinating and start working!","e1t":"Ertelemeyi bırak ve çalışmaya başla!","e2":"To procrastinate over a decision.","e2t":"Bir karar konusunda ayak sürümek."},{"w":"procure","tr":"temin etmek / tedarik etmek","te":"Verb","tt":"Fiil","de":"To get something, especially with difficulty","dt":"Bir şeyi, özellikle zorlukla elde etmek","e1":"We managed to procure the necessary equipment.","e1t":"Gerekli ekipmanı temin etmeyi başardık.","e2":"To procure information.","e2t":"Bilgi sağlamak (edinmek)."},{"w":"prod","tr":"dürtmek / uyarmak / teşvik etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push someone with your finger; or to encourage","dt":"Birini parmakla dürtmek; veya teşvik etmek","e1":"She prodded him in the ribs.","e1t":"Onu kaburgasından dürttü.","e2":"He needs a prod to start working.","e2t":"Çalışmaya başlamak için bir dürtülmeye (uyarıya) ihtiyacı var."},{"w":"prodigy","tr":"dahi çocuk / harika çocuk","te":"Noun","tt":"İsim","de":"A young person who has a great natural ability","dt":"Doğal yeteneği çok yüksek olan genç kişi","e1":"A child prodigy in music.","e1t":"Müzik dehası bir çocuk.","e2":"Mathematical prodigy.","e2t":"Matematik dehası."},{"w":"profane","tr":"dinden uzak / saygısız / kutsal olmayan","te":"Adjective/Verb","tt":"Showing no respect for a god or holy things","de":"Tanrıya veya kutsal şeylere saygı göstermeyen","dt":"Profane language (swearing).","e1":"Küfürlü (saygısız) dil.","e1t":"Profane art.","e2":"Din dışı (ladini) sanat.","e2t":""},{"w":"profess","tr":"açıkça söylemek / iddia etmek / (din) seçmek","te":"Verb","tt":"Fiil","de":"To state something publicly or claim something","dt":"Bir şeyi kamuoyuna açıklamak veya iddia etmek","e1":"He professed his innocence.","e1t":"Masum olduğunu iddia etti.","e2":"To profess an interest in history.","e2t":"Tarihe ilgi duyduğunu beyan etmek."},{"w":"prolific","tr":"üretken / bereketli / çok eser veren","te":"Adjective","tt":"Sıfat","de":"Producing a great number of something","dt":"Bir şeyden çok sayıda üreten","e1":"A prolific writer.","e1t":"Çok eser veren (üretken) bir yazar.","e2":"Prolific species.","e2t":"Çok üreyen türler."},{"w":"prolong","tr":"uzatmak / devam ettirmek","te":"Verb","tt":"Fiil","de":"To make something last longer","dt":"Bir şeyin daha uzun sürmesini sağlamak","e1":"To prolong a meeting.","e1t":"Bir toplantıyı uzatmak.","e2":"The operation prolonged his life by five years.","e2t":"Ameliyat ömrünü beş yıl uzattı."},{"w":"prominent","tr":"öne çıkan / seçkin / belirgin","te":"Adjective","tt":"Sıfat","de":"Important and well","dt":"known; or sticking out","e1":"Önemli ve tanınmış; veya çıkıntılı","e1t":"A prominent politician.","e2":"Seçkin bir siyasetçi.","e2t":"Prominent nose."},{"w":"prone","tr":"yatkın / meyilli / yüzükoyun","te":"Adjective","tt":"Sıfat","de":"Likely to experience something bad; or lying face down","dt":"Kötü bir şeyi tecrübe etmeye yatkın; veya yüzükoyun yatmak","e1":"He is prone to accidents.","e1t":"Kazalara yatkındır.","e2":"To lie prone on the floor.","e2t":"Yerde yüzükoyun yatmak."},{"w":"pronoun","tr":"zamir / adıl","te":"Noun","tt":"İsim","de":"A word that is used instead of a noun","dt":"Bir ismin yerine kullanılan kelime","e1":"\"He\", \"she\", and \"it\" are pronouns.","e1t":"\"He\", \"she\" ve \"it\" zamirdir.","e2":"Relative pronoun.","e2t":"İlgi zamiri."},{"w":"pronounce","tr":"telaffuz etmek / duyurmak / ilan etmek","te":"Verb","tt":"Fiil","de":"To make the sound of a word; or to state officially","dt":"Bir kelimenin sesini çıkarmak; veya resmi olarak duyurmak","e1":"How do you pronounce your name?","e1t":"İsmini nasıl telaffuz ediyorsun?","e2":"The judge pronounced the sentence.","e2t":"Yargıç kararı (hükmü) açıkladı."},{"w":"prop","tr":"destek / desteklemek / sahne eşyası","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object used to support something; or an object in a play","dt":"Bir şeyi destekleyen nesne; veya tiyatro aksesuarı","e1":"To use a stick as a prop.","e1t":"Bir sopayı destek olarak kullanmak.","e2":"Stage props.","e2t":"Sahne dekorları."},{"w":"propaganda","tr":"propaganda","te":"Noun","tt":"İsim","de":"Information used to influence people's opinions","dt":"İnsanların fikirlerini etkilemek için kullanılan bilgi","e1":"Government propaganda.","e1t":"Hükümet propagandası.","e2":"To spread propaganda.","e2t":"Propaganda yaymak."},{"w":"propagate","tr":"yaymak / üretmek / çoğalmak","te":"Verb","tt":"Fiil","de":"To spread ideas; or (of plants) to produce new ones","dt":"Fikirleri yaymak; veya (bitki için) yeni örnekler üretmek","e1":"To propagate a belief.","e1t":"Bir inancı yaymak.","e2":"Plants propagate through seeds.","e2t":"Bitkiler tohum yoluyla çoğalır."},{"w":"propel","tr":"itmek / sevk etmek","te":"Verb","tt":"Fiil","de":"To push someone or something forward","dt":"Birini veya bir şeyi ileri doğru itmek","e1":"The boat is propelled by a motor.","e1t":"Tekne bir motorla itiliyor (hareket ediyor).","e2":"To propel someone into fame.","e2t":"Birini şöhrete taşımak (itmek)."},{"w":"prophecy","tr":"kehanet","te":"Noun","tt":"İsim","de":"A statement that says what will happen in the future","dt":"Gelecekte ne olacağını söyleyen ifade","e1":"To fulfill a prophecy.","e1t":"Bir kehaneti gerçekleştirmek.","e2":"A prophecy of doom.","e2t":"Kıyamet kehaneti."},{"w":"prophet","tr":"peygamber / kahin","te":"Noun","tt":"İsim","de":"A person who is believed to be chosen by God to give messages","dt":"Tanrı tarafından mesaj iletmek için seçildiğine inanılan kişi","e1":"The Prophet Muhammad.","e1t":"Hz. Muhammed.","e2":"A prophet of modern technology.","e2t":"Modern teknolojinin öncüsü (kahini)."},{"w":"proposition","tr":"önerme / teklif / fikir","te":"Noun/Verb","tt":"İsim/Fiil","de":"An idea or a plan, especially in business","dt":"Özellikle iş dünyasında bir fikir veya plan","e1":"I have a business proposition for you.","e1t":"Senin için bir iş teklifim var.","e2":"A logical proposition.","e2t":"Mantıksal önerme."},{"w":"propriety","tr":"uygunluk / görgü / adap","te":"Noun","tt":"İsim","de":"Correct moral behavior or rules","dt":"Doğru ahlaki davranış veya kurallar","e1":"To behave with propriety.","e1t":"Edeple (adaba uygun) davranmak.","e2":"Doubts about the propriety of the decision.","e2t":"Kararın uygunluğu konusundaki şüpheler."},{"w":"prose","tr":"düz yazı / nesir","te":"Noun/Adjective/Verb","tt":"Written language in its ordinary form","de":"Olağan formundaki yazılı dil","dt":"His prose is very clear.","e1":"Onun düz yazısı (üslubu) çok nettir.","e1t":"Poetry and prose.","e2":"Şiir ve düz yazı.","e2t":""},{"w":"prosecute","tr":"dava açmak / kovuşturmak / sürdürmer","te":"Verb","tt":"Fiil","de":"To officially accuse someone of a crime in court","dt":"Birini mahkemede resmi olarak suçlamak","e1":"He was prosecuted for theft.","e1t":"Hırsızlıktan dava edildi.","e2":"To prosecute a war.","e2t":"Bir savaşı sürdürmek (yürütmek)."},{"w":"prospect","tr":"olasılık / manzara / umut / (maden) aramak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The possibility that something will happen","dt":"Bir şeyin olma olasılığı","e1":"The prospect of a new job.","e1t":"Yeni bir iş olasılığı (umudu).","e2":"No prospect of success.","e2t":"Başarı şansı yok."},{"w":"prosper","tr":"zenginleşmek / başarılı olmak / işleri yolunda gitmek","te":"Verb","tt":"Fiil","de":"To be successful, especially by making money","dt":"Özellikle para kazanarak başarılı olmak","e1":"The business began to prosper.","e1t":"İşler yolunda gitmeye (zenginleşmeye) başladı.","e2":"To prosper in a career.","e2t":"Kariyerinde başarılı olmak."},{"w":"prosperity","tr":"refah / zenginlik / başarı","te":"Noun","tt":"İsim","de":"The state of being successful and having money","dt":"Başarılı olma ve paraya sahip olma durumu","e1":"Economic prosperity.","e1t":"Ekonomik refah.","e2":"A period of peace and prosperity.","e2t":"Barış ve refah dönemi."},{"w":"protégé","tr":"korunan kimse / gözde (öğrenci vb.)","te":"Noun","tt":"İsim","de":"A person who is helped by a more experienced person","dt":"Daha deneyimli biri tarafından yardım edilen (korunan) kişi","e1":"He was the professor's protégé.","e1t":"Profesörün gözde öğrencisiydi (himayesindeydi).","e2":"To train a protégé.","e2t":"Bir yetiştirme (korunan kişi) eğitmek."},{"w":"protocol","tr":"protokol / resmi kurallar / tutanak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Formal rules for behavior; or a set of rules for computers","dt":"Davranış için resmi kurallar; veya bilgisayar kuralları seti","e1":"Diplomatic protocol.","e1t":"Diplomatik protokol.","e2":"TCP/IP protocol.","e2t":"TCP/IP protokolü."},{"w":"prototype","tr":"prototip / ilk örnek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The first model of something new","dt":"Yeni bir şeyin ilk modeli","e1":"A prototype of a new car.","e1t":"Yeni bir arabanın prototipi.","e2":"We are testing the prototype.","e2t":"Prototipi test ediyoruz."},{"w":"proud","tr":"gururlu / mağrur / görkemli","te":"Adjective","tt":"Sıfat","de":"Feeling satisfaction and pleasure in an achievement","dt":"Bir başarıdan dolayı memnuniyet ve keyif duyan","e1":"I’m very proud of you.","e1t":"Seninle gurur duyuyorum.","e2":"A proud tradition.","e2t":"Köklü (gurur duyulan) bir gelenek."},{"w":"proverb","tr":"atasözü","te":"Noun","tt":"İsim","de":"A short well","dt":"known statement that gives advice","e1":"Tavsiye veren, kısa ve bilinen ifade","e1t":"As the proverb says...","e2":"Atasözünün dediği gibi...","e2t":"Turkish proverbs."},{"w":"provoke","tr":"kışkırtmak / neden olmak / damarına basmak","te":"Verb","tt":"Fiil","de":"To cause a reaction; or to make someone angry","dt":"Bir tepkiye neden olmak; veya birini kızdırmak","e1":"The decision provoked a lot of anger.","e1t":"Karar büyük öfkeye neden oldu.","e2":"Don't provoke the dog.","e2t":"Köpeği kışkırtma."},{"w":"prowl","tr":"sinsi sinsi dolaşmak / (av için) gezinmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move around quietly while hunting or hiding","dt":"Avlanırken veya saklanırken sessizce dolaşmak","e1":"A tiger on the prowl.","e1t":"Av peşinde dolaşan bir kaplan.","e2":"To prowl the streets at night.","e2t":"Gece sokaklarda sinsi sinsi dolaşmak."},{"w":"proximity","tr":"yakınlık","te":"Noun","tt":"İsim","de":"The state of being near in space or time","dt":"Mekan veya zaman açısından yakın olma durumu","e1":"Proximity to the airport.","e1t":"Havaalanına yakınlık.","e2":"The proximity of the two events.","e2t":"İki olayın birbirine yakınlığı."},{"w":"proxy","tr":"vekil / elçi / temsilci","te":"Noun","tt":"İsim","de":"A person who has the power to act for another","dt":"Başkası adına hareket etme yetkisi olan kişi","e1":"To vote by proxy.","e1t":"Vekalet yoluyla oy kullanmak.","e2":"Proxy server (computing).","e2t":"Vekil sunucu."},{"w":"prudent","tr":"tedbirli / ihtiyatlı / sağduyulu","te":"Adjective","tt":"Sıfat","de":"Careful and avoiding unnecessary risks","dt":"Dikkatli ve gereksiz risklerden kaçınan","e1":"It is prudent to save money for the future.","e1t":"Gelecek için para biriktirmek tedbirli bir davranıştır.","e2":"A prudent decision.","e2t":"Sağduyulu bir karar."},{"w":"psychiatry","tr":"psikiyatri","te":"Noun","tt":"İsim","de":"The branch of medicine concerned with mental illness","dt":"Akıl hastalıklarıyla ilgilenen tıp dalı","e1":"He decided to specialize in psychiatry.","e1t":"Psikiyatri alanında uzmanlaşmaya karar verdi.","e2":"Child psychiatry.","e2t":"Çocuk psikiyatrisi."},{"w":"psychic","tr":"medyum / ruhsal / zihinsel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the mind or having special mental powers","dt":"Zihinle ilgili veya özel zihinsel güçlere sahip olan","e1":"Psychic powers.","e1t":"Medyum güçleri (doğaüstü yetenekler).","e2":"Psychic trauma.","e2t":"Ruhsal travma."},{"w":"pulley","tr":"makara","te":"Noun","tt":"İsim","de":"A wheel with a rope around it used for lifting heavy things","dt":"Ağır şeyleri kaldırmak için kullanılan, etrafında ip olan çark","e1":"A system of pulleys.","e1t":"Makaralar sistemi.","e2":"To lift the engine with a pulley.","e2t":"Motoru bir makara ile kaldırmak."},{"w":"pulp","tr":"posa / kağıt hamuru / ucuz roman","te":"Noun/Verb","tt":"İsim/Fiil","de":"A soft, wet mass of material","dt":"Yumuşak, ıslak madde kütlesi","e1":"Fruit pulp.","e1t":"Meyve posası.","e2":"Wood pulp for making paper.","e2t":"Kağıt yapımı için odun hamuru."},{"w":"pun","tr":"kelime oyunu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A humorous use of a word that has two meanings","dt":"İki anlamı olan bir kelimenin mizahi kullanımı","e1":"He is always making terrible puns.","e1t":"Her zaman berbat kelime oyunları yapıyor.","e2":"To play on words (pun).","e2t":"Kelime oyunu yapmak."},{"w":"punctual","tr":"dakik","te":"Adjective","tt":"Sıfat","de":"Arriving or doing something at the correct time","dt":"Bir şeyi doğru zamanda yapan veya gelen","e1":"Please be punctual for the meeting.","e1t":"Lütfen toplantı için dakik olun.","e2":"He is always very punctual.","e2t":"O her zaman çok dakiktir."},{"w":"punctuate","tr":"noktalama işaretleri koymak / kesintiye uğratmak","te":"Verb","tt":"Fiil","de":"To use marks in writing; or to interrupt repeatedly","dt":"Yazıda işaretler kullanmak; veya sık sık kesintiye uğratmak","e1":"You need to punctuate your sentences correctly.","e1t":"Cümlelerinizi doğru noktalamalısınız.","e2":"The speech was punctuated by applause.","e2t":"Konuşma alkışlarla sık sık kesildi."},{"w":"puncture","tr":"delmek / patlak / delik","te":"Verb/Noun","tt":"Fiil/İsim","de":"A small hole made by a sharp object","dt":"Keskin bir nesnenin açtığı küçük delik","e1":"I had a puncture on the way home.","e1t":"Eve gelirken lastiğim patladı (delindi).","e2":"To puncture a tire.","e2t":"Lastiği delmek."},{"w":"puppet","tr":"kukla","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A toy moved by strings or a person controlled by another","dt":"İplerle hareket ettirilen oyuncak veya başkası tarafından kontrol edilen kişi","e1":"A puppet show.","e1t":"Kukla gösterisi.","e2":"The dictator was just a puppet of the foreign power.","e2t":"Diktatör sadece yabancı gücün bir kuklasıydı."},{"w":"purge","tr":"temizlemek (istenmeyenleri) / tasfiye / arınmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get rid of people or things that are not wanted","dt":"İstenmeyen kişi veya şeylerden kurtulmak","e1":"The party purged its extremist members.","e1t":"Parti, aşırılık yanlısı üyelerini tasfiye etti.","e2":"To purge the system of errors.","e2t":"Sistemi hatalardan arındırmak."},{"w":"purify","tr":"arıtmak / temizlemek / saflaştırmak","te":"Verb","tt":"Fiil","de":"To make something pure by removing dirty parts","dt":"Kirli kısımları çıkararak bir şeyi saf hale getirmek","e1":"To purify water.","e1t":"Suyu arıtmak.","e2":"Plants help to purify the air.","e2t":"Bitkiler havayı temizlemeye yardımcı olur."},{"w":"purse","tr":"cüzdan (kadın) / para çantası / dudak bükmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small bag for carrying money; or to tighten lips","dt":"Para taşımak için küçük çanta; veya dudakları sıkmak","e1":"She took a coin out of her purse.","e1t":"Cüzdanından bir bozuk para çıkardı.","e2":"To purse one's lips.","e2t":"Dudaklarını büzmek (hoşnutsuzluk ifadesi)."},{"w":"quack","tr":"vakvak / şarlatan / sahte doktor","te":"Noun/Verb/Adj","tt":"The sound of a duck; or a person who pretends to be a doctor","de":"Ördek sesi; veya doktor taklidi yapan kişi","dt":"The ducks were quacking in the pond.","e1":"Ördekler gölette vakvaklıyordu.","e1t":"Don't listen to that quack.","e2":"O şarlatana kulak asma.","e2t":""},{"w":"quaint","tr":"antika / tuhaf ama hoş / otantik","te":"Adjective","tt":"Sıfat","de":"Attractive because it is unusual and old","dt":"fashioned","e1":"Sıra dışı ve eski moda olduğu için çekici olan","e1t":"A quaint little village.","e2":"Şirin ve otantik küçük bir köy.","e2t":"Quaint customs."},{"w":"quake","tr":"titremek / sarsılmak / deprem","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shake because you are cold or frightened; or an earthquake","dt":"Soğuktan veya korkudan titremek; veya deprem","e1":"He was quaking with fear.","e1t":"Korkudan titriyordu.","e2":"A major quake (earthquake) hit the region.","e2t":"Bölgeyi büyük bir deprem vurdu."},{"w":"qualm","tr":"vicdan azabı / endişe / şüphe","te":"Noun","tt":"İsim","de":"A feeling of doubt or worry about whether you are doing the right thing","dt":"Doğru şeyi yapıp yapmadığına dair şüphe veya endişe hissi","e1":"He had no qualms about lying.","e1t":"Yalan söyleme konusunda hiçbir vicdan azabı (şüphesi) yoktu.","e2":"Without any qualms.","e2t":"Hiç çekinmeden."},{"w":"quandary","tr":"ikilem / kararsızlık / açmaz","te":"Noun","tt":"İsim","de":"A state of not being able to decide what to do","dt":"Ne yapacağına karar verememe durumu","e1":"I'm in a bit of a quandary.","e1t":"Biraz ikilemdeyim.","e2":"To face a moral quandary.","e2t":"Ahlaki bir ikilemle karşı karşıya kalmak."},{"w":"quarantine","tr":"karantina / karantinaya almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A period of time when people/animals are kept apart to stop disease","dt":"Hastalığı durdurmak için ayrılan süre","e1":"The ship was kept in quarantine.","e1t":"Gemi karantinada tutuldu.","e2":"To quarantine a sick animal.","e2t":"Hasta bir hayvanı karantinaya almak."},{"w":"quartet","tr":"dörtlü","te":"Noun","tt":"İsim","de":"A group of four people, especially musicians","dt":"Dört kişilik grup, özellikle müzisyenler","e1":"A string quartet.","e1t":"Yaylı çalgılar dörtlüsü.","e2":"A quartet of world leaders.","e2t":"Dört dünya lideri."},{"w":"quartz","tr":"kuvars","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A hard mineral often used in watches","dt":"Genellikle saatlerde kullanılan sert bir mineral","e1":"A quartz watch.","e1t":"Kuvars saat.","e2":"Rose quartz.","e2t":"Pembe kuvars."},{"w":"queer","tr":"tuhaf / garip / kuir","te":"Adjective/Noun/Verb","tt":"Strange or unusual; or related to LGBTQ+","de":"Garip veya alışılmadık; veya LGBTQ+ ile ilgili","dt":"I have a queer feeling that something is wrong.","e1":"Bir şeylerin yanlış olduğuna dair tuhaf bir hissim var.","e1t":"Queer studies.","e2":"Kuir çalışmaları.","e2t":""},{"w":"quench","tr":"(susuzluk) gidermek / söndürmek / dindirmek","te":"Verb","tt":"Fiil","de":"To satisfy a thirst; or to stop a fire","dt":"Susuzluğu gidermek; veya bir ateşi söndürmek","e1":"To quench your thirst with a cold drink.","e1t":"Soğuk bir içecekle susuzluğunu gidermek.","e2":"To quench a fire.","e2t":"Ateşi söndürmek."},{"w":"quibble","tr":"kelime oyunu yapmak / yersiz eleştirmek / önemsiz ayrıntıya takılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To argue about small, unimportant details","dt":"Küçük, önemsiz detaylar hakkında tartışmak","e1":"Let’s not quibble over details.","e1t":"Detaylar üzerinde boşuna tartışmayalım.","e2":"A minor quibble.","e2t":"Küçük bir itiraz."},{"w":"quilt","tr":"yorgan / kapitone","te":"Noun/Verb","tt":"İsim/Fiil","de":"A decorative cover for a bed","dt":"Yatak için süslü örtü (yorgan)","e1":"A handmade quilt.","e1t":"El yapımı yorgan.","e2":"Quilted jacket.","e2t":"Kapitone ceket."},{"w":"quiver","tr":"titremek / ürpermek / ok kılıfı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shake slightly; or a case for arrows","dt":"Hafifçe titremek; veya ok kabı","e1":"Her voice quivered with emotion.","e1t":"Sesi duygudan titredi.","e2":"A quiver of arrows.","e2t":"Ok kılıfı."},{"w":"quiz","tr":"sınav / küçük test / sorgulamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short competition of knowledge; or to ask questions","dt":"Kısa bilgi yarışması; veya soru sormak/sorgulamak","e1":"A pub quiz.","e1t":"Bilgi yarışması.","e2":"The police quizzed the witness.","e2t":"Polis tanığı sorguladı."},{"w":"quota","tr":"kota / kontenjan / pay","te":"Noun","tt":"İsim","de":"A fixed amount of something that is allowed or needed","dt":"İzin verilen veya gereken sabit miktar","e1":"The country has a fishing quota.","e1t":"Ülkenin balıkçılık kotası var.","e2":"To meet your sales quota.","e2t":"Satış kotanı doldurmak."},{"w":"rabies","tr":"kuduz","te":"Noun","tt":"İsim","de":"A serious disease of dogs that can be passed to humans","dt":"İnsanlara bulaşabilen ciddi bir köpek hastalığı","e1":"He was bitten by a dog with rabies.","e1t":"Kuduz bir köpek tarafından ısırıldı.","e2":"Rabies vaccination.","e2t":"Kuduz aşısı."},{"w":"rack","tr":"raf / askı / eziyet etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A frame for holding or hanging things; or to cause pain","dt":"Bir şeyleri tutmak veya asmak için çerçeve; veya acı çektirmek","e1":"A luggage rack.","e1t":"Bagaj rafı.","e2":"Rack of lamb (meat).","e2t":"Kuzu kaburga."},{"w":"racket","tr":"raket / gürültü / şamata / haraç çetesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object for hitting a ball; or a loud noise; or illegal business","dt":"Topa vurma aleti; veya yüksek gürültü; veya yasadışı iş","e1":"Tennis racket.","e1t":"Tenis raketi.","e2":"Stop that racket!","e2t":"Şu gürültüyü kesin!"},{"w":"radiant","tr":"parlak / ışık saçan / çok mutlu","te":"Adjective","tt":"Sıfat","de":"Shining brightly; or showing great happiness","dt":"Parlak bir şekilde ışıldayan; veya büyük mutluluk gösteren","e1":"The radiant sun.","e1t":"Parlak güneş.","e2":"She looked radiant in her wedding dress.","e2t":"Gelinliği içinde ışık saçıyordu (çok mutluydu)."},{"w":"radius","tr":"yarıçap","te":"Noun","tt":"İsim","de":"The distance from the center of a circle to its edge","dt":"Bir dairenin merkezinden kenarına olan mesafe","e1":"Within a five","e1t":"mile radius.","e2":"Beş millik bir yarıçap içinde.","e2t":"The radius of a circle."},{"w":"raffish","tr":"sefih / hafifmeşrep / bohem","te":"Adjective","tt":"Sıfat","de":"Attractive but not completely respectable or moral","dt":"Çekici ama tam olarak saygın veya ahlaklı olmayan","e1":"He had a raffish charm.","e1t":"Sefih (bohem) bir çekiciliği vardı.","e2":"A raffish lifestyle.","e2t":"Kuralsız (hafifmeşrep) bir yaşam tarzı."},{"w":"raft","tr":"sal / çok sayı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small flat boat made of wood","dt":"Odunlardan yapılmış küçük düz tekne","e1":"We crossed the river on a raft.","e1t":"Nehri bir salla geçtik.","e2":"A raft of new measures.","e2t":"Bir dizi (çok sayıda) yeni önlem."},{"w":"rag","tr":"paçavra / eski bez / magazin gazetesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of old cloth; or a poor quality newspaper","dt":"Eski kumaş parçası; veya düşük kaliteli gazete","e1":"Use a rag to clean the floor.","e1t":"Zemini temizlemek için bir bez (paçavra) kullan.","e2":"From rags to riches (poor to wealthy).","e2t":"Fakirlikten zenginliğe."},{"w":"raid","tr":"baskın / akın / soygun","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden attack by the police or an enemy","dt":"Polis veya düşman tarafından yapılan ani saldırı","e1":"A police raid on a house.","e1t":"Bir eve yapılan polis baskını.","e2":"Air raid.","e2t":"Hava saldırısı."},{"w":"rail","tr":"ray / korkuluk / raylı sistem","te":"Noun/Verb","tt":"İsim/Fiil","de":"A metal bar for trains; or to complain loudly","dt":"Trenler için metal çubuk; veya yüksek sesle şikayet etmek","e1":"High","e1t":"speed rail.","e2":"Hızlı tren (raylı sistem).","e2t":"To lean against the rail."},{"w":"rake","tr":"tırmık / tırmıklamak / çapkın","te":"Noun/Verb","tt":"İsim/Fiil","de":"A garden tool with long teeth; or to search","dt":"Uzun dişli bahçe aleti; veya araştırmak","e1":"To rake the leaves.","e1t":"Yaprakları tırmıklamak.","e2":"A garden rake.","e2t":"Bahçe tırmığı."},{"w":"rally","tr":"miting / toparlanmak / ralli","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large public meeting; or to recover strength","dt":"Büyük halk toplantısı; veya güç toplamak","e1":"A political rally.","e1t":"Siyasi miting.","e2":"The stock market rallied.","e2t":"Borsa toparlandı."},{"w":"ram","tr":"koç / toslamak / çarpmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A male sheep; or to hit something with force","dt":"Erkek koyun; veya bir şeye güçle vurmak","e1":"The car rammed into the fence.","e1t":"Araba çite tosladı (çarptı).","e2":"Battering ram.","e2t":"Koçbaşı."},{"w":"ramble","tr":"boş boş dolaşmak / uzun uzun ve kopuk konuşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk for pleasure; or to talk for a long time without a clear point","dt":"Zevk için yürümek; veya net bir noktası olmadan uzunca konuşmak","e1":"We spent the day rambling through the woods.","e1t":"Günü ormanda dolaşarak geçirdik.","e2":"He rambled on for hours about his cat.","e2t":"Kedisi hakkında saatlerce (konuyu dağıtarak) konuştu."},{"w":"ramp","tr":"rampa / eğimli yol","te":"Noun/Verb","tt":"İsim/Fiil","de":"A slope that joins two different levels","dt":"İki farklı seviyeyi birleştiren eğim","e1":"Wheelchair ramp.","e1t":"Tekerlekli sandalye rampası.","e2":"Exit ramp on a highway.","e2t":"Otoyol çıkış rampası."},{"w":"rampant","tr":"yaygın / azgın / kontrolsüz","te":"Adjective","tt":"Sıfat","de":"Existing or spreading everywhere in a way that cannot be controlled","dt":"Kontrol edilemez bir şekilde her yere yayılan","e1":"Rampant inflation.","e1t":"Kontrolsüz (yüksek) enflasyon.","e2":"Corruption is rampant in the system.","e2t":"Sistemde yolsuzluk kol geziyor (çok yaygın)."},{"w":"ranch","tr":"çiftlik (büyük)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very large farm for raising cattle or horses","dt":"Sığır veya at yetiştirmek için kullanılan çok büyük çiftlik","e1":"He works on a cattle ranch.","e1t":"Bir sığır çiftliğinde çalışıyor.","e2":"Ranch house.","e2t":"Çiftlik evi."},{"w":"random","tr":"rastgele","te":"Adjective/Noun/Adv","tt":"Happening by chance rather than according to a plan","de":"Bir plandan ziyade şans eseri gerçekleşen","dt":"A random sample.","e1":"Rastgele bir örneklem.","e1t":"At random.","e2":"Gelişigüzel (rastgele).","e2t":""},{"w":"ransom","tr":"fidye / fidye ödemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money paid to free a kidnapped person","dt":"Kaçırılan birini serbest bırakmak için ödenen para","e1":"The kidnappers demanded a huge ransom.","e1t":"Kaçırıcılar devasa bir fidye istedi.","e2":"To hold someone to ransom.","e2t":"Birini fidye için tutmak (rehin almak)."},{"w":"rap","tr":"hafifçe vurmak / tıkırtı / rap müziği","te":"Noun/Verb","tt":"İsim/Fiil","de":"A quick sharp hit; or a type of music","dt":"Hızlı ve sert vuruş; veya bir müzik türü","e1":"A rap on the door.","e1t":"Kapıda bir tıkırtı.","e2":"Rap artist.","e2t":"Rap sanatçısı."},{"w":"rape","tr":"tecavüz / tecavüz etmek / yağmalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The crime of forcing someone to have sex; or to destroy","dt":"Birini cinselliğe zorlama suçu; veya tahrip etmek","e1":"To be charged with rape.","e1t":"Tecavüzle suçlanmak.","e2":"The rape of the environment.","e2t":"Çevrenin tahribi (yağmalanması)."},{"w":"rascal","tr":"haylaz / yaramaz / köftehor","te":"Noun","tt":"İsim","de":"A person, especially a child, who behaves badly but is still liked","dt":"Kötü davranan ama yine de sevilen kişi (özellikle çocuk)","e1":"Come here, you little rascal!","e1t":"Gel buraya, seni küçük haylaz!","e2":"A lovable rascal.","e2t":"Sevimli bir yaramaz."},{"w":"rash","tr":"aceleci / döküntü / kaşıntı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Done without thinking; or red spots on the skin","dt":"Düşünmeden yapılan; veya ciltteki kırmızı lekeler","e1":"Don't make any rash decisions.","e1t":"Aceleci kararlar verme.","e2":"I have a heat rash on my arm.","e2t":"Kolumda sıcaklık döküntüsü (kaşıntı) var."},{"w":"rat","tr":"sıçan / kalleş / ele vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small animal with a long tail; or a dishonest person","dt":"Uzun kuyruklu küçük hayvan; veya güvenilmez kişi","e1":"I smell a rat (I suspect something is wrong).","e1t":"Şüpheli bir durum seziyorum (bit yeniği var).","e2":"He ratted on his friends.","e2t":"Arkadaşlarini ele verdi (ispiyonladı)."},{"w":"ratify","tr":"onaylamak / tasdik etmek","te":"Verb","tt":"Fiil","de":"To make an agreement official by signing it","dt":"Bir anlaşmayı imzalayarak resmi hale getirmek","e1":"The parliament ratified the treaty.","e1t":"Parlamento antlaşmayı onayladı (tasdik etti).","e2":"To ratify a constitution.","e2t":"Bir anayasayı onaylamak."},{"w":"ratio","tr":"oran / nispet","te":"Noun","tt":"İsim","de":"A relationship between two amounts","dt":"İki miktar arasındaki ilişki","e1":"The ratio of men to women is 2 to 1.","e1t":"Erkeklerin kadınlara oranı 2'ye 1'dir.","e2":"Student","e2t":"teacher ratio."},{"w":"ration","tr":"istihkak / karneye bağlamak / kısıtlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fixed amount of food or fuel allowed","dt":"İzin verilen sabit yiyecek veya yakıt miktarı","e1":"Daily rations for soldiers.","e1t":"Askerler için günlük istihkak.","e2":"Fuel was rationed during the war.","e2t":"Savaş sırasında yakıt karneye bağlandı."},{"w":"rattle","tr":"tıkırdamak / sarsmak / çıngırak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make short sharp sounds; or to make someone nervous","dt":"Kısa sert sesler çıkarmak; veya birini telaşlandırmak","e1":"The windows rattled in the wind.","e1t":"Pencereler rüzgarda tıkırdadı.","e2":"The news rattled him.","e2t":"Haberler onu sarstı (telaşlandırdı)."},{"w":"ravage","tr":"harap etmek / yağmalamat / tahribat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cause great damage to something","dt":"Bir şeye büyük zarar vermek","e1":"The forest was ravaged by fire.","e1t":"Orman yangınla harap oldu.","e2":"The ravages of time.","e2t":"Zamanın tahribatı."},{"w":"ray","tr":"ışın / hüzme / vatoz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A narrow line of light or energy","dt":"İnce ışık veya enerji hattı","e1":"A ray of sunshine.","e1t":"Bir güneş ışığı hüzmesi.","e2":"X","e2t":"rays."},{"w":"razor","tr":"ustura / tıraş bıçağı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A tool with a sharp blade for shaving","dt":"Tıraş olmak için kullanılan keskin bıçaklı alet","e1":"Electric razor.","e1t":"Elektrikli tıraş makinesi.","e2":"Razor","e2t":"sharp (very sharp)."},{"w":"realm","tr":"alem / krallık / alan","te":"Noun","tt":"İsim","de":"A kingdom; or an area of interest or activity","dt":"Bir krallık; veya ilgi/faaliyet alanı","e1":"The realm of possibility.","e1t":"Olasılıklar alemi (alanı).","e2":"Within the spiritual realm.","e2t":"Ruhani alem içinde."},{"w":"reap","tr":"hasat etmek / (kar vb.) toplamak","te":"Verb","tt":"Fiil","de":"To cut and collect a crop; or to get a reward","dt":"Mahsulü kesip toplamak; veya ödül/kar elde etmek","e1":"You reap what you sow.","e1t":"Ne ekersen onu biçersin.","e2":"To reap the benefits.","e2t":"Faydalarını toplamak (yararlanmak)."},{"w":"rear","tr":"arka / büyütmek / şaha kalkmak","te":"Noun/Adj/Verb","tt":"The back part; or to care for young; or to rise up","de":"Arka kısım; veya çocuk/hayvan büyütmek; veya ayağa kalkmak","dt":"The rear of the building.","e1":"Binanın arkası.","e1t":"He was reared in a small village.","e2":"Küçük bir köyde büyütüldü.","e2t":""},{"w":"rebate","tr":"para iadesi / indirim","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money that is returned to you","dt":"Size geri ödenen para miktarı","e1":"A tax rebate.","e1t":"Vergi iadesi.","e2":"You can claim a rebate on your energy bill.","e2t":"Enerji faturanızda indirim (iade) talep edebilirsiniz."},{"w":"rebound","tr":"geri sekmek / toparlanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To bounce back; or to improve after a bad period","dt":"Geri fırlamak; veya kötü bir dönemden sonra düzelmek","e1":"The ball rebounded off the post.","e1t":"Top direkten döndü (sekti).","e2":"The stock market rebounded.","e2t":"Borsa tekrar yükselişe geçti (toparlandı)."},{"w":"rebuke","tr":"azarlamak / fırça atmak / sitem","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak angrily because of someone's behavior","dt":"Birinin davranışı nedeniyle öfkeli konuşmak","e1":"He was rebuked for being late.","e1t":"Geç kaldığı için azarlandı.","e2":"A sharp rebuke.","e2t":"Sert bir azar."},{"w":"recede","tr":"geri çekilmek / uzaklaşmak / (saç) dökülmek","te":"Verb","tt":"Fiil","de":"To move further away into the distance","dt":"Uzaklaşarak geriye doğru gitmek","e1":"The flood waters finally began to recede.","e1t":"Sel suları sonunda çekilmeye başladı.","e2":"A receding hairline.","e2t":"Açılan (gerileyen) saç çizgisi."},{"w":"recess","tr":"teneffüs / ara / girinti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A period of time when work or study stops; or a space","dt":"Çalışma veya eğitime verilen ara; veya girinti/oyuk","e1":"The court is in recess.","e1t":"Mahkemeye ara verildi.","e2":"School recess.","e2t":"Okul teneffüsü."},{"w":"reciprocal","tr":"karşılıklı / çift taraflı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Involving two people or groups who agree to help each other","dt":"Birbirine yardım etmeyi kabul eden iki kişi veya grup arasındaki","e1":"A reciprocal agreement.","e1t":"Karşılıklı anlaşma.","e2":"Reciprocal feelings.","e2t":"Karşılıklı duygular."},{"w":"recite","tr":"ezberden okumak / anlatmak","te":"Verb","tt":"Fiil","de":"To say a piece of writing aloud from memory","dt":"Bir metni hafızadan yüksek sesle söylemek","e1":"He recited a poem.","e1t":"Bir şiir okudu.","e2":"To recite the facts.","e2t":"Gerçekleri (tek tek) anlatmak."},{"w":"reckless","tr":"dikkatsiz / umursamaz / gözü kara","te":"Adjective","tt":"Sıfat","de":"Doing something dangerous without worrying about results","dt":"Sonuçları umursamadan tehlikeli bir şey yapan","e1":"Reckless driving.","e1t":"Dikkatsiz (tehlikeli) sürüş.","e2":"He is reckless with his money.","e2t":"Parasını düşüncesizce harcıyor."},{"w":"reckon","tr":"hesaplamak / sanmak / güvenmek","te":"Verb","tt":"Fiil","de":"To calculate; or to believe something is likely","dt":"Hesaplamak; veya bir şeyin muhtemel olduğuna inanmak","e1":"I reckon it will rain later.","e1t":"Sanırım (tahmin ediyorum) birazdan yağmur yağacak.","e2":"A force to be reckoned with.","e2t":"Hesaba katılması (ciddiye alınması) gereken bir güç."},{"w":"reclaim","tr":"geri istemek / ıslah etmek (toprak)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take back something that was yours; or to make land useful","dt":"Sizinkini geri almak; veya toprağı kullanışlı hale getirmek","e1":"I managed to reclaim my lost luggage.","e1t":"Kayıp bagajımı geri almayı başardım.","e2":"To reclaim land from the sea.","e2t":"Denizden toprak kazanmak (ıslah etmek)."},{"w":"recoil","tr":"geri tepmek / ürkmek / geri çekilmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move back because of fear or a physical force","dt":"Korkudan veya fiziksel bir güçle geriye gitmek","e1":"She recoiled in horror.","e1t":"Dehşetle geri çekildi (ürktü).","e2":"The rifle recoiled against his shoulder.","e2t":"Tüfek omzuna doğru geri tepti."},{"w":"recollect","tr":"hatırlamak / anımsamak","te":"Verb","tt":"Fiil","de":"To remember something","dt":"Bir şeyi hatırlamak","e1":"I can't recollect his name.","e1t":"Adını hatırlayamıyorum.","e2":"As far as I can recollect...","e2t":"Hatırlayabildiğim kadarıyla..."},{"w":"reconcile","tr":"barıştırmak / uzlaştırmak / bağdaştırmak","te":"Verb","tt":"Fiil","de":"To make people friendly again; or to find a way to make ideas agree","dt":"İnsanları tekrar barıştırmak; veya fikirleri uyumlu hale getirmek","e1":"The two friends finally reconciled.","e1t":"İki arkadaş sonunda barıştı.","e2":"To reconcile work and family life.","e2t":"İş ve aile hayatını bağdaştırmak."},{"w":"reconstruct","tr":"yeniden inşa etmek / canlandırmak (olay)","te":"Verb","tt":"Fiil","de":"To build something again; or to describe a past event","dt":"Bir şeyi tekrar inşa etmek; veya geçmiş bir olayı betimlemek","e1":"The city was reconstructed after the war.","e1t":"Şehir savaştan sonra yeniden inşa edildi.","e2":"To reconstruct a crime scene.","e2t":"Bir suç mahallini canlandırmak."},{"w":"recount","tr":"anlatmak / yeniden saymak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To tell a story; or to count again","dt":"Bir hikaye anlatmak; veya tekrar saymak","e1":"He recounted his adventures in Africa.","e1t":"Afrika'daki maceralarını anlattı.","e2":"To recount the votes.","e2t":"Oyları yeniden saymak."},{"w":"rectangle","tr":"dikdörtgen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A shape with four straight sides and four 90","dt":"degree angles","e1":"Dört düz kenarı ve dört dik açısı olan şekil","e1t":"The table is a perfect rectangle.","e2":"Masa tam bir dikdörtgendir.","e2t":"Rectangular box."},{"w":"rectify","tr":"düzeltmek / doğrultmak","te":"Verb","tt":"Fiil","de":"To correct something that is wrong","dt":"Yanlış olan bir şeyi düzeltmek","e1":"We must take steps to rectify the situation.","e1t":"Durumu düzeltmek için adımlar atmalıyız.","e2":"To rectify an error.","e2t":"Bir hatayı düzeltmek."},{"w":"recur","tr":"nüksetmek / tekrar etmek","te":"Verb","tt":"Fiil","de":"To happen many times or happen again","dt":"Birçok kez olmak veya tekrar gerçekleşmek","e1":"The problem keeps recurring.","e1t":"Sorun nüksetmeye (tekrarlamaya) devam ediyor.","e2":"A recurring dream.","e2t":"Tekrar eden rüya."},{"w":"redeem","tr":"telafi etmek / (kupon) bozdurmak / kurtarmak","te":"Verb","tt":"Fiil","de":"To make something seem less bad; or to exchange a coupon","dt":"Bir şeyi daha az kötü göstermek; veya kupon takas etmek","e1":"This one good performance redeemed the whole play.","e1t":"Bu iyi performans tüm oyunu kurtardı (telafi etti).","e2":"To redeem a voucher.","e2t":"Hediye çekini bozdurmak."},{"w":"redundant","tr":"gereksiz (fazlalık) / işten çıkarılmış","te":"Adjective","tt":"Sıfat","de":"More than is needed; or without a job because not needed","dt":"Gerekenden fazla; veya ihtiyaç kalmadığı için işsiz","e1":"The word is redundant in this sentence.","e1t":"Bu kelime bu cümlede gereksiz (fazlalık).","e2":"50 workers were made redundant.","e2t":"50 işçi işten çıkarıldı."},{"w":"reed","tr":"kamış / saz / (enstrüman) dil","te":"Noun","tt":"İsim","de":"A tall plant like grass that grows in water; or part of a woodwind","dt":"Suda yetişen uzun bitki; veya nefesli çalgı parçası","e1":"Reeds by the lake.","e1t":"Göl kenarındaki sazlar.","e2":"The clarinet uses a wooden reed.","e2t":"Klarnet tahta bir dil (kamış) kullanır."},{"w":"reef","tr":"resif / sığlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of rocks or coral just above or below the sea","dt":"Denizin hemen altında veya üstündeki kaya/mercan hattı","e1":"Coral reef.","e1t":"Mercan resifi.","e2":"Great Barrier Reef.","e2t":"Büyük Set Resifi."},{"w":"reel","tr":"makara / sendelemek / fırıl fırıl dönmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A cylinder for wire or film; or to walk unsteadily","dt":"Tel veya film için silindir; veya sendelemek","e1":"A reel of thread.","e1t":"Bir makara iplik.","e2":"He reeled back in surprise.","e2t":"Şaşkınlıkla geriye doğru sendeledi."},{"w":"referee","tr":"hakem / referans kişi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who controls a sports match; or a person for a job application","dt":"Spor maçını yöneten kişi; veya iş başvurusu için referans","e1":"The referee blew the whistle.","e1t":"Hakem düdüğü çaldı.","e2":"Who is your academic referee?","e2t":"Akademik referansın kim?"},{"w":"refine","tr":"arıtmak / geliştirmek / inceltmek","te":"Verb","tt":"Fiil","de":"To make a substance pure; or to improve something","dt":"Bir maddeyi saf hale getirmek; veya bir şeyi geliştirmek","e1":"Crude oil is refined into petrol.","e1t":"Ham petrol arıtılarak benzine dönüştürülür.","e2":"To refine your language skills.","e2t":"Dil becerilerini geliştirmek (mükemmelleştirmek)."},{"w":"refrain","tr":"kaçınmak / sakınmak / nakarat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop yourself from doing something; or a chorus","dt":"Bir şeyi yapmaktan kendini alıkoymak; veya nakarat","e1":"Please refrain from smoking.","e1t":"Lütfen sigara içmekten kaçının.","e2":"A familiar refrain.","e2t":"Tanıdık bir nakarat."},{"w":"refugee","tr":"mülteci / sığınmacı","te":"Noun","tt":"İsim","de":"A person who has been forced to leave their country","dt":"Ülkesini terk etmeye zorlanmış kişi","e1":"A refugee camp.","e1t":"Mülteci kampı.","e2":"To grant asylum to refugees.","e2t":"Mültecilere sığınma hakkı tanımak."},{"w":"refund","tr":"geri ödeme / para iadesi yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money that is given back to you","dt":"Size geri verilen para miktarı","e1":"Can I get a refund?","e1t":"Para iadesi alabilir miyim?","e2":"The store refunded my money.","e2t":"Mağaza paramı iade etti."},{"w":"refusal","tr":"ret / geri çevirme","te":"Noun","tt":"İsim","de":"The act of saying \"no\" to something","dt":"Bir şeye \"hayır\" deme eylemi","e1":"His refusal to help was a surprise.","e1t":"Yardım etmeyi reddetmesi bir sürprizdi.","e2":"A flat refusal.","e2t":"Kesin bir ret."},{"w":"refute","tr":"çürütmek / yalanlamak","te":"Verb","tt":"Fiil","de":"To prove that a statement is wrong","dt":"Bir ifadenin yanlış olduğunu kanıtlamak","e1":"To refute an argument.","e1t":"Bir iddiayı çürütmek.","e2":"He refuted the allegations.","e2t":"İddiaları yalanladı (çürüttü)."},{"w":"regain","tr":"geri kazanmak / yeniden elde etmek","te":"Verb","tt":"Fiil","de":"To get something back that you have lost","dt":"Kaybedilen bir şeyi geri almak","e1":"He finally regained consciousness.","e1t":"Sonunda bilinci yerine geldi (kazandı).","e2":"To regain control.","e2t":"Kontrolü yeniden ele geçirmek."},{"w":"regal","tr":"kraliyetle ilgili / görkemli / muhteşem","te":"Adjective","tt":"Sıfat","de":"Suitable for a king or queen","dt":"Bir kral veya kraliçeye uygun","e1":"She has a regal manner.","e1t":"Görkemli (kraliyet vari) bir tavrı var.","e2":"A regal feast.","e2t":"Muhteşem bir ziyafet."},{"w":"regime","tr":"rejim / yönetim biçimi / diyet","te":"Noun","tt":"İsim","de":"A particular government; or a system of diet or exercise","dt":"Belirli bir hükümet; veya beslenme/egzersiz sistemi","e1":"A military regime.","e1t":"Askeri rejim.","e2":"A strict exercise regime.","e2t":"Sıkı bir egzersiz düzeni (rejimi)."},{"w":"regulate","tr":"düzenlemek / denetlemek","te":"Verb","tt":"Fiil","de":"To control an activity or process by rules","dt":"Bir faaliyeti kurallarla kontrol etmek","e1":"The government regulates the price of milk.","e1t":"Hükümet süt fiyatlarını düzenler.","e2":"To regulate traffic.","e2t":"Trafiği düzenlemek."},{"w":"rehabilitate","tr":"rehabilite etmek / iyileştirmek / itibarını iade etmek","te":"Verb","tt":"Fiil","de":"To help someone return to a normal life","dt":"Birinin normal hayata dönmesine yardım etmek","e1":"To rehabilitate a prisoner.","e1t":"Bir mahkumu rehabilite etmek.","e2":"To rehabilitate an old building.","e2t":"Eski bir binayı restore etmek (iyileştirmek)."},{"w":"rehearse","tr":"prova yapmak / tekrarlamak","te":"Verb","tt":"Fiil","de":"To practice a play or piece of music","dt":"Bir oyunu veya müzik parçasını uygulamak","e1":"The band is rehearsing for the concert.","e1t":"Grup konser için prova yapıyor.","e2":"To rehearse an argument.","e2t":"Bir iddiayı (zihinde) tekrarlamak."},{"w":"reign","tr":"hüküm sürmek / saltanat","te":"Verb/Noun","tt":"Fiil/İsim","de":"The period of time when a king or queen rules","dt":"Bir kral veya kraliçenin hüküm sürdüğü süre","e1":"During the reign of Queen Victoria.","e1t":"Kraliçe Victoria'nın saltanatı sırasında.","e2":"Silence reigned in the room.","e2t":"Odada sessizlik hakimdi (hüküm sürdü)."},{"w":"rein","tr":"dizgin / kontrol etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long leather band used to control a horse","dt":"Atı kontrol etmek için kullanılan deri kayış","e1":"To pull on the reins.","e1t":"Dizginleri çekmek.","e2":"You need to rein in your spending.","e2t":"Harcamalarını dizginlemen (kontrol etmen) gerekiyor."},{"w":"reincarnation","tr":"reenkarnasyon / ruh göçü","te":"Noun","tt":"İsim","de":"The belief that the soul is born again in another body","dt":"Ruhun başka bir bedende tekrar doğduğuna dair inanç","e1":"Many people believe in reincarnation.","e1t":"Birçok insan reenkarnasyona inanır.","e2":"A story about reincarnation.","e2t":"Ruh göçü hakkında bir hikaye."},{"w":"reinforce","tr":"güçlendirmek / pekiştirmek / takviye etmek","te":"Verb","tt":"Fiil","de":"To make something stronger; to provide more support","dt":"Bir şeyi daha güçlü hale getirmek; daha fazla destek sağlamak","e1":"These results reinforce my theory.","e1t":"Bu sonuçlar teorimi pekiştiriyor.","e2":"To reinforce a wall with steel.","e2t":"Bir duvarı çelikle güçlendirmek."},{"w":"reject","tr":"reddetmek / geri çevirmek / ıskarta","te":"Verb/Noun","tt":"Fiil/İsim","de":"To refuse to accept or believe something","dt":"Bir şeyi kabul etmeyi veya inanmayı reddetmek","e1":"The committee rejected the proposal.","e1t":"Komite öneriyi reddetti.","e2":"Factory rejects (damaged goods).","e2t":"Fabrika defolu ürünleri (ıskartalar)."},{"w":"rejoice","tr":"sevinmek / coşmak / bayram etmek","te":"Verb","tt":"Fiil","de":"To feel or show great happiness","dt":"Büyük mutluluk hissetmek veya göstermek","e1":"Everyone rejoiced at the news of victory.","e1t":"Zafer haberiyle herkes çok sevindi.","e2":"To rejoice in someone's success.","e2t":"Birinin başarısıyla sevinmek."},{"w":"relapse","tr":"nüksetmek / kötüleşmek / tekerrür","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become ill again after improving","dt":"İyileştikten sonra tekrar hastalanmak","e1":"He had a relapse and was taken back to hospital.","e1t":"Hastalığı nüksetti ve tekrar hastaneye kaldırıldı.","e2":"To relapse into bad habits.","e2t":"Kötü alışkanlıklara geri dönmek."},{"w":"relate","tr":"ilişkilendirmek / anlatmak / bağ kurmak","te":"Verb","tt":"Fiil","de":"To find a connection between things; to tell a story","dt":"Şeyler arasında bağ kurmak; bir hikaye anlatmak","e1":"I can relate to your problem.","e1t":"Sorununu anlayabiliyorum (bağ kurabiliyorum).","e2":"He related his adventures to us.","e2t":"Maceralarını bize anlattı."},{"w":"relay","tr":"iletmek / bayrak yarışı / aktarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pass a message or information to someone","dt":"Bir mesajı veya bilgiyi birine iletmek","e1":"The satellites relay signals around the world.","e1t":"Uydular sinyalleri dünya geneline iletir.","e2":"Relay race.","e2t":"Bayrak yarışı."},{"w":"relentless","tr":"amansız / dur durak bilmeyen / acımasız","te":"Adjective","tt":"Sıfat","de":"Continuing in a severe or determined way","dt":"Şiddetli veya kararlı bir şekilde devam eden","e1":"The relentless heat of the desert.","e1t":"Çölün amansız sıcağı.","e2":"Relentless pressure to succeed.","e2t":"Başarmak için dur durak bilmeyen baskı."},{"w":"reliable","tr":"güvenilir / emin","te":"Adjective","tt":"Sıfat","de":"Able to be trusted or believed","dt":"Güvenilebilen veya inanılabilen","e1":"A reliable car.","e1t":"Güvenilir bir araba.","e2":"He is a very reliable worker.","e2t":"O çok güvenilir bir çalışandır."},{"w":"relic","tr":"kalıntı / emanet / yadigar","te":"Noun","tt":"İsim","de":"An object from the past that has survived","dt":"Geçmişten günümüze kalan nesne","e1":"Ancient Egyptian relics.","e1t":"Antik Mısır kalıntıları.","e2":"The building is a relic of the colonial era.","e2t":"Bina, sömürge döneminden kalma bir yadigardır."},{"w":"relieve","tr":"rahatlatmak / dindirmek / (görevi) devralmak","te":"Verb","tt":"Fiil","de":"To make pain or worry less; to take someone's place","dt":"Acıyı veya endişeyi azaltmak; birinin yerini almak","e1":"This medicine will relieve your headache.","e1t":"Bu ilaç baş ağrınızı hafifletecektir.","e2":"To relieve a guard.","e2t":"Bir nöbetçiden görevi devralmak."},{"w":"relinquish","tr":"feragat etmek / bırakmak / vazgeçmek","te":"Verb","tt":"Fiil","de":"To give up something such as power or a responsibility","dt":"Güç veya sorumluluk gibi bir şeyi bırakmak","e1":"He relinquished his claim to the throne.","e1t":"Taht üzerindeki hak iddiasından vazgeçti.","e2":"To relinquish control.","e2t":"Kontrolü bırakmak."},{"w":"relish","tr":"tadını çıkarmak / büyük zevk / sos","te":"Verb/Noun","tt":"Fiil/İsim","de":"To enjoy something greatly","dt":"Bir şeyden büyük zevk almak","e1":"I always relish a challenge.","e1t":"Zorluklardan her zaman zevk alırım.","e2":"To eat with relish (with great enjoyment).","e2t":"İştahla (büyük zevkle) yemek."},{"w":"reluctant","tr":"isteksiz / gönülsüz","te":"Adjective","tt":"Sıfat","de":"Not wanting to do something","dt":"Bir şeyi yapmayı istemeyen","e1":"He was reluctant to sign the contract.","e1t":"Sözleşmeyi imzalama konusunda isteksizdi.","e2":"Reluctant agreement.","e2t":"Gönülsüzce kabul etme."},{"w":"rely","tr":"güvenmek / bel bağlamak / muhtaç olmak","te":"Verb","tt":"Fiil","de":"To trust someone or something to help you","dt":"Size yardım etmesi için birine veya bir şeye güvenmek","e1":"You can always rely on me.","e1t":"Bana her zaman güvenebilirsin.","e2":"To rely on technology.","e2t":"Teknolojiye bel bağlamak."},{"w":"remainder","tr":"kalan / bakiye / artan","te":"Noun/Verb","tt":"İsim/Fiil","de":"The part of something that is left","dt":"Bir şeyin geri kalan kısmı","e1":"I'll spend the remainder of the day at home.","e1t":"Günün geri kalanını evde geçireceğim.","e2":"The remainder of the division (math).","e2t":"Bölme işleminde kalan."},{"w":"remarkable","tr":"dikkate değer / sıra dışı / şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Very unusual or noticeable in a good way","dt":"Çok sıra dışı veya iyi anlamda fark edilen","e1":"He has a remarkable memory.","e1t":"Dikkate değer bir hafızası var.","e2":"A remarkable achievement.","e2t":"Şaşırtıcı bir başarı."},{"w":"remedy","tr":"çare / ilaç / çözüm","te":"Noun/Verb","tt":"İsim/Fiil","de":"A successful way of curing an illness or solving a problem","dt":"Bir hastalığı iyileştirmenin veya bir sorunu çözmenin yolu","e1":"A natural remedy for a cold.","e1t":"Soğuk algınlığı için doğal bir çare.","e2":"To remedy a situation.","e2t":"Bir durumu düzeltmek (çare bulmak)."},{"w":"reminisce","tr":"anıları yad etmek / geçmişten konuşmak","te":"Verb","tt":"Fiil","de":"To talk or write about enjoyable past experiences","dt":"Keyifli geçmiş deneyimler hakkında konuşmak veya yazmak","e1":"They spent the evening reminiscing about their school days.","e1t":"Akşamı okul günlerini yad ederek geçirdiler.","e2":"REMINISCENT OF (reminding of).","e2t":"..."},{"w":"remnant","tr":"kalıntı / parça / bakiye","te":"Noun","tt":"İsim","de":"A small piece or amount of something that is left","dt":"Bir şeyden geriye kalan küçük parça veya miktar","e1":"The remnants of a meal.","e1t":"Yemek artıkları (kalıntıları).","e2":"Remnants of a former civilization.","e2t":"Eski bir medeniyetin kalıntıları."},{"w":"remorse","tr":"vicdan azabı / pişmanlık","te":"Noun","tt":"İsim","de":"A strong feeling of guilt and regret","dt":"Güçlü bir suçluluk ve pişmanlık hissi","e1":"He felt no remorse for what he had done.","e1t":"Yaptığı şey için hiç vicdan azabı duymadı.","e2":"To be full of remorse.","e2t":"Pişmanlık dolu olmak."},{"w":"renaissance","tr":"rönesans / yeniden doğuş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A period of new interest in art and learning","dt":"Sanat ve öğrenime duyulan ilginin yeniden canlandığı dönem","e1":"The Italian Renaissance.","e1t":"İtalyan Rönesansı.","e2":"A renaissance in traditional music.","e2t":"Geleneksel müzikte bir yeniden doğuş."},{"w":"render","tr":"hale getirmek / sunmak / (yardım) etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cause someone to be in a particular state; to give help","dt":"Birini belirli bir duruma sokmak; yardım sağlamak","e1":"The accident rendered him unconscious.","e1t":"Kaza onu baygın hale getirdi.","e2":"To render assistance.","e2t":"Yardım etmek (sunmak)."},{"w":"rendezvous","tr":"randevu / buluşma yeri","te":"Noun/Verb","tt":"İsim/Fiil","de":"An arrangement to meet someone at a particular time and place","dt":"Belirli bir yer ve zamanda biriyle buluşma anlaşması","e1":"We set a rendezvous for 8 PM.","e1t":"Saat 20:00 için bir randevu ayarladık.","e2":"A secret rendezvous.","e2t":"Gizli bir buluşma."},{"w":"renew","tr":"yenilemek / tazelemek","te":"Verb","tt":"Fiil","de":"To make something new or valid again","dt":"Bir şeyi tekrar yeni veya geçerli hale getirmek","e1":"I need to renew my passport.","e1t":"Pasaportumu yenilemem gerekiyor.","e2":"To renew a contract.","e2t":"Sözleşmeyi yenilemek."},{"w":"renounce","tr":"reddetmek / vazgeçmek / feragat etmek","te":"Verb","tt":"Fiil","de":"To officially state that you no longer have a belief or right","dt":"Bir inanç veya haktan artık vazgeçtiğini resmi olarak bildirmek","e1":"He renounced his citizenship.","e1t":"Vatandaşlığından feragat etti (vazgeçti).","e2":"To renounce violence.","e2t":"Şiddeti reddetmek."},{"w":"renovate","tr":"yenilemek (bina vb.) / restore etmek","te":"Verb","tt":"Fiil","de":"To repair and decorate a building so that it is in good condition","dt":"Bir binayı iyi durumda olması için onarmak ve dekore etmek","e1":"They are renovating an old farmhouse.","e1t":"Eski bir çiftlik evini yeniliyorlar (restore ediyorlar).","e2":"To renovate a bathroom.","e2t":"Banyoyu yenilemek."},{"w":"renown","tr":"ün / şöhret / nam","te":"Noun","tt":"İsim","de":"The state of being famous","dt":"Ünlü olma durumu","e1":"A painter of international renown.","e1t":"Uluslararası üne sahip bir ressam.","e2":"To win renown.","e2t":"Şöhret kazanmak."},{"w":"rent","tr":"kira / kiralamak / yırtık","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money paid for using a room or car; or to pay this money","dt":"Oda veya araba kullanımı için ödenen para","e1":"How much is the rent?","e1t":"Kira ne kadar?","e2":"To rent a car for the weekend.","e2t":"Hafta sonu için araba kiralamak."},{"w":"repeal","tr":"yürürlükten kaldırmak / feshetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To officially end a law","dt":"Bir yasayı resmi olarak sona erdirmek","e1":"The law was repealed in 1960.","e1t":"Yasa 1960'ta yürürlükten kaldırıldı.","e2":"To repeal a tax.","e2t":"Bir vergiyi kaldırmak (feshetmek)."},{"w":"repel","tr":"itmek / tiksindirmek / püskürtmek","te":"Verb","tt":"Fiil","de":"To push away; or to cause a feeling of strong dislike","dt":"Uzaklaştırmak; veya güçlü bir hoşnutsuzluk hissi yaratmak","e1":"Magnets can repel each other.","e1t":"Mıknatıslar birbirini itebilir.","e2":"The smell repelled me.","e2t":"Koku beni tiksindirdi."},{"w":"repent","tr":"tövbe etmek / pişman olmak","te":"Verb","tt":"Fiil","de":"To be very sorry for something bad you have done","dt":"Yaptığınız kötü bir şeyden dolayı çok üzgün olmak","e1":"He repented of his sins.","e1t":"Günahları için tövbe etti.","e2":"It's never too late to repent.","e2t":"Tövbe etmek için asla geç değildir."},{"w":"repetition","tr":"tekrar / yineleme","te":"Noun","tt":"İsim","de":"The act of doing or saying something again","dt":"Bir şeyi tekrar yapma veya söyleme eylemi","e1":"Repetition helps you remember vocabulary.","e1t":"Tekrar etmek kelimeleri hatırlamanıza yardımcı olur.","e2":"Constant repetition.","e2t":"Sürekli tekrar."},{"w":"replenish","tr":"yeniden doldurmak / tazelemek","te":"Verb","tt":"Fiil","de":"To fill something up again","dt":"Bir şeyi tekrar doldurmak","e1":"To replenish the water supply.","e1t":"Su stoğunu yeniden doldurmak.","e2":"We need to replenish our stocks.","e2t":"Stoklarımızı tazelememiz (doldurmamız) gerekiyor."},{"w":"replica","tr":"kopya / tıpatıp aynısı","te":"Noun","tt":"İsim","de":"An exact copy of something","dt":"Bir şeyin tam kopyası","e1":"A replica of the Eiffel Tower.","e1t":"Eyfel Kulesi'nin bir kopyası.","e2":"Exact replica.","e2t":"Birebir kopya."},{"w":"repress","tr":"bastırmak / zapt etmek / kontrol altına almak","te":"Verb","tt":"Fiil","de":"To control a feeling or a group of people by force","dt":"Bir duyguyu veya bir grubu zorla kontrol etmek","e1":"He tried to repress a smile.","e1t":"Gülümsemesini bastırmaya çalıştı.","e2":"To repress a rebellion.","e2t":"Bir isyanı bastırmak."},{"w":"reprieve","tr":"erteleme (ceza) / geçici rahatlama / durdurma","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official order that stops or delays a punishment","dt":"Bir cezayı durduran veya erteleyen resmi emir","e1":"The prisoner was granted a last","e1t":"minute reprieve.","e2":"Mahkuma son dakika ertelemesi (ceza durdurulması) verildi.","e2t":"To offer a temporary reprieve."},{"w":"reproach","tr":"kınamak / sitem etmek / suçlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To criticize someone for not doing something expected","dt":"Beklenen bir şeyi yapmadığı için birini eleştirmek","e1":"His mother reproached him for not calling.","e1t":"Annesi onu aramadığı için sitem etti (kınadı).","e2":"Beyond reproach (perfect).","e2t":"Kusursuz (kınanamaz)."},{"w":"reproduce","tr":"çoğalmak / kopyalamak / yeniden üretmek","te":"Verb","tt":"Fiil","de":"To produce young; or to make a copy of something","dt":"Yavru üretmek; veya bir şeyin kopyasını yapmak","e1":"Bacteria reproduce very quickly.","e1t":"Bakteriler çok hızlı çoğalır.","e2":"To reproduce a famous painting.","e2t":"Ünlü bir tabloyu kopyalamak."},{"w":"reptile","tr":"sürüngen","te":"Noun","tt":"İsim","de":"An animal that has cold blood and skin covered in scales","dt":"Soğuk kanlı ve pullarla kaplı derisi olan hayvan","e1":"Snakes and lizards are reptiles.","e1t":"Yılanlar ve kertenkeleler sürüngendir.","e2":"Reptile house (in a zoo).","e2t":"Sürüngen evi."},{"w":"republic","tr":"cumhuriyet","te":"Noun","tt":"İsim","de":"A country without a king or queen, where leaders are elected","dt":"Kralı olmayan, liderlerin seçildiği ülke","e1":"The Republic of Turkey.","e1t":"Türkiye Cumhuriyeti.","e2":"To establish a republic.","e2t":"Cumhuriyet kurmak."},{"w":"repudiate","tr":"reddetmek / tanımamak / bağını koparmak","te":"Verb","tt":"Fiil","de":"To refuse to accept something or someone","dt":"Bir şeyi veya birini kabul etmeyi reddetmek","e1":"He repudiated the allegations.","e1t":"İddiaları reddetti (tanımadı).","e2":"To repudiate a debt.","e2t":"Bir borcu tanımadığını beyan etmek."},{"w":"repulsive","tr":"itici / iğrenç / antipatik","te":"Adjective","tt":"Sıfat","de":"Extremely unpleasant or causing strong dislike","dt":"Son derece nahoş veya güçlü bir nefret uyandıran","e1":"A repulsive smell.","e1t":"İğrenç bir koku.","e2":"I find his behavior repulsive.","e2t":"Onun davranışını itici buluyorum."},{"w":"reputation","tr":"itibar / ün / şöhret","te":"Noun","tt":"İsim","de":"The opinion that people have about someone or something","dt":"İnsanların biri veya bir şey hakkındaki görüşü","e1":"The hotel has a good reputation.","e1t":"Otelin iyi bir itibarı var.","e2":"To protect your reputation.","e2t":"İtibarını korumak."},{"w":"requisite","tr":"gerekli / şart / gereken","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Necessary for a particular purpose","dt":"Belirli bir amaç için gerekli olan","e1":"He lacks the requisite skills for the job.","e1t":"İş için gereken becerilere sahip değil.","e2":"Self","e2t":"confidence is a requisite for success."},{"w":"rescue","tr":"kurtarmak / imdat / kurtarma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To save someone from a dangerous situation","dt":"Birini tehlikeli bir durumdan kurtarmak","e1":"The helicopter arrived to rescue the survivors.","e1t":"Helikopter hayatta kalanları kurtarmak için geldi.","e2":"Rescue team.","e2t":"Kurtarma ekibi."},{"w":"resemble","tr":"benzemek / andırmak","te":"Verb","tt":"Fiil","de":"To look like or be similar to someone or something","dt":"Birine veya bir şeye benzemek","e1":"You resemble your father.","e1t":"Babana benziyorsun.","e2":"The two plants resemble each other.","e2t":"İki bitki birbirini andırıyor."},{"w":"resent","tr":"içerlemek / kızmak / gücenmek","te":"Verb","tt":"Fiil","de":"To feel angry because you have been forced to accept something","dt":"Bir şeyi kabul etmeye zorlandığınız için öfke duymak","e1":"He resents being told what to do.","e1t":"Ne yapacağının söylenmesine içerliyor.","e2":"I resent your comments.","e2t":"Yorumlarına güceniyorum (kızıyorum)."},{"w":"reserve","tr":"ayırtmak / yedek / ihtiyat / çekince","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep something for a particular purpose; or a supply","dt":"Bir şeyi belirli bir amaç için tutmak; veya stok/yedek","e1":"I'd like to reserve a table for two.","e1t":"İki kişilik bir masa ayırtmak istiyorum.","e2":"Gold reserves.","e2t":"Altın rezervleri."},{"w":"reservoir","tr":"baraj gölü / su deposu / hazne","te":"Noun","tt":"İsim","de":"A large natural or artificial lake used as a source of water","dt":"Su kaynağı olarak kullanılan büyük doğal veya yapay göl","e1":"The city's main reservoir.","e1t":"Şehrin ana su deposu (baraj gölü).","e2":"A reservoir of knowledge.","e2t":"Bilgi haznesi."},{"w":"reside","tr":"ikamet etmek / yerleşmek","te":"Verb","tt":"Fiil","de":"To live in a particular place","dt":"Belirli bir yerde yaşamak","e1":"He resides in Istanbul.","e1t":"İstanbul'da ikamet ediyor.","e2":"The family resides in a small apartment.","e2t":"Aile küçük bir dairede ikamet ediyor."},{"w":"residue","tr":"tortu / kalıntı / artık","te":"Noun","tt":"İsim","de":"A substance that remains after a process","dt":"Bir süreçten sonra geriye kalan madde","e1":"Pesticide residues on fruit.","e1t":"Meyveler üzerindeki tarım ilacı kalıntıları.","e2":"Sticky residue.","e2t":"Yapışkan tortu."},{"w":"resign","tr":"istifa etmek / vazgeçmek","te":"Verb","tt":"Fiil","de":"To officially tell your employer that you are leaving your job","dt":"İşten ayrıldığını işverene resmi olarak bildirmek","e1":"He resigned from his post as manager.","e1t":"Müdürlük görevinden istifa etti.","e2":"To resign one's position.","e2t":"Makamından istifa etmek."},{"w":"resilient","tr":"dirençli / esnek / çabuk toparlanan","te":"Adjective","tt":"Sıfat","de":"Able to become strong again after a difficult situation","dt":"Zor bir durumdan sonra tekrar güçlenebilen","e1":"She is a very resilient person.","e1t":"O çok dirençli biridir.","e2":"Resilient materials (returning to original shape).","e2t":"Esnek (dirençli) malzemeler."},{"w":"resonance","tr":"rezonans / yankı / tını","te":"Noun","tt":"İsim","de":"The quality in a sound of being deep and full","dt":"Bir sesin derin ve tok olma özelliği","e1":"The resonance of his voice.","e1t":"Sesinin tınısı (yankısı).","e2":"Magnetic resonance imaging (MRI).","e2t":"Manyetik rezonans görüntüleme (MR)."},{"w":"resort","tr":"başvurmak / tatil yeri / çare","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where people go for holidays; or to do something bad because there is no other choice","dt":"İnsanların tatil için gittiği yer; veya çaresizlikten kötü bir yola başvurmak","e1":"A popular ski resort.","e1t":"Popüler bir kayak merkezi.","e2":"As a last resort.","e2t":"Son çare olarak."},{"w":"resource","tr":"kaynak / olanak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that a country or person has and can use","dt":"Bir ülkenin veya kişinin sahip olduğu ve kullanabileceği şey","e1":"Natural resources like oil and coal.","e1t":"Petrol ve kömür gibi doğal kaynaklar.","e2":"Human resources (HR).","e2t":"İnsan kaynakları."},{"w":"respiration","tr":"solunum / nefes alma","te":"Noun","tt":"İsim","de":"The act of breathing","dt":"Nefes alma eylemi","e1":"Artificial respiration.","e1t":"Suni teneffüs.","e2":"Respiratory system.","e2t":"Solunum sistemi."},{"w":"responsible","tr":"sorumlu / güvenilir","te":"Adjective","tt":"Sıfat","de":"To have control over something and be the one who is blamed if it goes wrong","dt":"Bir şey üzerinde kontrole sahip olmak ve bir hata durumunda suçlanan kişi olmak","e1":"Who is responsible for this mess?","e1t":"Bu karışıklıktan kim sorumlu?","e2":"A responsible adult.","e2t":"Sorumlu (güvenilir) bir yetişkin."},{"w":"restitution","tr":"iade / tazminat / eski haline getirme","te":"Noun","tt":"İsim","de":"The return of objects that were stolen; or payment for damage","dt":"Çalınan eşyaların iadesi; veya hasar için ödeme","e1":"The court ordered the restitution of the property.","e1t":"Mahkeme mülkün iadesine karar verdi.","e2":"Restitution of historical artifacts.","e2t":"Tarihi eserlerin iadesi."},{"w":"restless","tr":"huzursuz / kıpır kıpır / uykusuz","te":"Adjective","tt":"Sıfat","de":"Unable to rest or relax because of worry or boredom","dt":"Endişe veya can sıkıntısı nedeniyle dinlenemeyen","e1":"A restless night.","e1t":"Uykusuz (huzursuz) bir gece.","e2":"The children were getting restless.","e2t":"Çocuklar huzursuzlanmaya (yerinde duramamaya) başlıyordu."},{"w":"restore","tr":"eski haline getirmek / onarmak / iade etmek","te":"Verb","tt":"Fiil","de":"To return something to its original condition","dt":"Bir şeyi orijinal durumuna döndürmek","e1":"To restore an old painting.","e1t":"Eski bir tabloyu restore etmek (onarmak).","e2":"Law and order were restored.","e2t":"Asayiş tekrar sağlandı (eski haline getirildi)."},{"w":"restrain","tr":"dizginlemek / kısıtlamak / engel olmak","te":"Verb","tt":"Fiil","de":"To control the actions or emotions of someone","dt":"Birinin eylemlerini veya duygularını kontrol etmek","e1":"He could barely restrain his anger.","e1t":"Öfkesini zar zor dizginleyebildi.","e2":"To restrain trade.","e2t":"Ticareti kısıtlamak."},{"w":"restrict","tr":"kısıtlamak / sınırlamak","te":"Verb","tt":"Fiil","de":"To limit the amount or range of something","dt":"Bir şeyin miktarını veya kapsamını sınırlamak","e1":"Speed is restricted to 30 mph.","e1t":"Hız 30 mil ile sınırlandırılmıştır.","e2":"To restrict access.","e2t":"Erişimi kısıtlamak."},{"w":"resume","tr":"devam ettirmek / yeniden başlamak / özgeçmiş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To start again after a pause; or a short summary of a person's career","dt":"Bir aradan sonra tekrar başlamak; veya bir kişinin kariyer özeti","e1":"The meeting will resume after lunch.","e1t":"Toplantı öğle yemeğinden sonra devam edecek.","e2":"To send a resume (CV) for a job.","e2t":"İş için özgeçmiş göndermek."},{"w":"retail","tr":"perakende / perakende satmak","te":"Noun/Verb/Adj/Adv","tt":"The activity of selling goods to the public","de":"Halka mal satma faaliyeti","dt":"Retail price.","e1":"Perakende satış fiyatı.","e1t":"The shoes retail at $50.","e2":"Ayakkabılar 50 dolara satılıyor.","e2t":""},{"w":"retain","tr":"muhafaza etmek / tutmak / unutmamak","te":"Verb","tt":"Fiil","de":"To continue to keep or have something","dt":"Bir şeyi saklamaya veya ona sahip olmaya devam etmek","e1":"He managed to retain his title.","e1t":"Unvanını korumayı (muhafaza etmeyi) başardı.","e2":"To retain information.","e2t":"Bilgiyi akılda tutmak."},{"w":"retaliate","tr":"misilleme yapmak / karşılık vermek","te":"Verb","tt":"Fiil","de":"To hurt someone who has hurt you","dt":"Size zarar verene zarar vererek karşılık vermek","e1":"If they attack us, we will retaliate.","e1t":"Bize saldırırlarsa misilleme yaparız.","e2":"Retaliatory measures.","e2t":"Misilleme önlemleri."},{"w":"retard","tr":"geciktirmek / yavaşlatmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something happen later or more slowly","dt":"Bir şeyin daha geç veya daha yavaş olmasını sağlamak","e1":"Cold weather retards the growth of plants.","e1t":"Soğuk hava bitkilerin büyümesini yavaşlatır.","e2":"Fire retardant.","e2t":"Yangın geciktirici."},{"w":"retention","tr":"akılda tutma / muhafaza / alıkoyma","te":"Noun","tt":"İsim","de":"The ability to keep or remember something","dt":"Bir şeyi saklama veya hatırlama yeteneği","e1":"Visual aids help customer retention.","e1t":"Görsel araçlar müşterinin akılda tutmasına yardımcı olur.","e2":"Water retention.","e2t":"Vücutta su tutulması (ödem)."},{"w":"reticent","tr":"suskun / ağzı sıkı / çekingen","te":"Adjective","tt":"Sıfat","de":"Unwilling to speak about your thoughts or feelings","dt":"Duygu ve düşünceleri hakkında konuşmaya isteksiz","e1":"He is very reticent about his private life.","e1t":"Özel hayatı konusunda çok suskundur.","e2":"A reticent manner.","e2t":"Çekingen bir tavır."},{"w":"retina","tr":"retina / ağ tabaka","te":"Noun","tt":"İsim","de":"The area at the back of the eye that receives light","dt":"Gözün arkasında ışığı alan bölge","e1":"Detached retina.","e1t":"Retina dekolmanı (ayrılması).","e2":"Retina scan.","e2t":"Retina taraması."},{"w":"retort","tr":"sert cevap vermek / terslemek / imbik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To answer someone quickly in an angry or funny way","dt":"Birine kızgın veya komik bir şekilde hızlıca cevap vermek","e1":"\"That's not true!\" he retorted.","e1t":"\"Bu doğru değil!\" diye tersledi (karşılık verdi).","e2":"A sharp retort.","e2t":"Sert bir cevap."},{"w":"retreat","tr":"geri çekilmek / inzivaya çekilmek / sığınak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move away from the enemy or a difficult situation","dt":"Düşmandan veya zor bir durumdan uzaklaşmak","e1":"The army was forced to retreat.","e1t":"Ordu geri çekilmek zorunda kaldı.","e2":"A mountain retreat (a quiet place).","e2t":"Dağ evi (huzurlu sığınak)."},{"w":"retrieve","tr":"geri almak / (bilgiye) erişmek / bulup getirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To find and bring back something","dt":"Bir şeyi bulup geri getirmek","e1":"The dog retrieved the ball.","e1t":"Köpek topu bulup getirdi.","e2":"To retrieve data from the computer.","e2t":"Bilgisayardan veri kurtarmak (erişmek)."},{"w":"retroactive","tr":"geçmişe etkili / geriye dönük","te":"Adjective","tt":"Sıfat","de":"(Of a law or pay increase) effective from a date in the past","dt":"(Yasa veya maaş artışı için) geçmişteki bir tarihten itibaren geçerli olan","e1":"A retroactive pay raise.","e1t":"Geriye dönük maaş artışı.","e2":"Retroactive legislation.","e2t":"Geçmişe etkili yasama."},{"w":"reunion","tr":"yeniden birleşme / toplantı (eski dostlar vb.)","te":"Noun","tt":"İsim","de":"A social event for a group of people who have not seen each other for a long time","dt":"Uzun süredir görüşmeyen insanların katıldığı sosyal etkinlik","e1":"A family reunion.","e1t":"Aile birleşmesi (toplantısı).","e2":"School reunion.","e2t":"Okul mezunlar günü."},{"w":"revelation","tr":"vahiy / ifşa / açığa çıkma","te":"Noun","tt":"İsim","de":"A surprising and previously unknown fact that is made known","dt":"Daha önce bilinmeyen şaşırtıcı bir gerçeğin açıklanması","e1":"Revelations about his private life.","e1t":"Özel hayatı hakkındaki ifşalar.","e2":"Divine revelation.","e2t":"İlahi vahiy."},{"w":"revenge","tr":"intikam / öç almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Harm done to someone as a punishment for harm they have done to you","dt":"Size verilen zararın karşılığı olarak başkasına verilen zarar","e1":"He wanted to get revenge on his enemies.","e1t":"Düşmanlarından intikam almak istedi.","e2":"A revenge attack.","e2t":"İntikam saldırısı."},{"w":"revenue","tr":"gelir / hasılat","te":"Noun","tt":"İsim","de":"Money that a company or government receives","dt":"Bir şirket veya hükümetin elde ettiği para","e1":"Tax revenue.","e1t":"Vergi geliri.","e2":"The company's annual revenue.","e2t":"Şirketin yıllık hasılatı."},{"w":"revere","tr":"saygı duymak / yüceltmek","te":"Verb","tt":"Fiil","de":"To admire and respect someone very much","dt":"Birine çok hayran olmak ve saygı duymak","e1":"He is revered as a national hero.","e1t":"Ulusal bir kahraman olarak saygı görüyor.","e2":"To revere the memory of...","e2t":"..."},{"w":"reverse","tr":"tersine çevirmek / geri geri gitmek / ters","te":"Verb/Noun/Adj","tt":"To change something to the opposite; or to drive backwards","de":"Bir şeyi tam tersine değiştirmek; veya geri geri sürmek","dt":"To reverse a decision.","e1":"Bir kararı tersine çevirmek.","e1t":"To drive in reverse.","e2":"Geri viteste (geri geri) sürmek.","e2t":""},{"w":"revise","tr":"gözden geçirmek (düzeltmek) / revize etmek / ders çalışmak (UK)","te":"Verb","tt":"Fiil","de":"To change something so that it is better or more correct","dt":"Bir şeyi daha iyi veya doğru olması için değiştirmek","e1":"Please revise the document.","e1t":"Lütfen belgeyi gözden geçirin (düzeltin).","e2":"I need to revise for my English exam.","e2t":"İngilizce sınavım için ders tekrarı yapmam (çalışmam) gerekiyor."},{"w":"revive","tr":"canlandırmak / diriltmek / yeniden popüler olmak","te":"Verb","tt":"Fiil","de":"To come back to life or health; or to start something again","dt":"Hayata veya sağlığa dönmek; veya bir şeyi tekrar başlatmak","e1":"The economy is starting to revive.","e1t":"Ekonomi canlanmaya başlıyor.","e2":"To revive an old tradition.","e2t":"Eski bir geleneği canlandırmak."},{"w":"revoke","tr":"iptal etmek / yürürlükten kaldırmak / geri çekmek","te":"Verb","tt":"Fiil","de":"To officially end a law, decision, or permission","dt":"Bir yasayı, kararı veya izni resmi olarak sona erdirmek","e1":"His driving license was revoked.","e1t":"Ehliyeti iptal edildi.","e2":"To revoke an agreement.","e2t":"Bir anlaşmayı feshetmek (iptal etmek)."},{"w":"revolt","tr":"isyan / ayaklanma / tiksinmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To protest against authority; or to cause strong dislike","dt":"Otoriteye karşı protesto etmek; veya güçlü bir hoşnutsuzluk yaratmak","e1":"The peasants revolted against the King.","e1t":"Köylüler Kral'a karşı ayaklandı.","e2":"The smell of the meat revolted me.","e2t":"Etin kokusu beni tiksindirdi."},{"w":"revolution","tr":"devrim / dönüş / ihtilal","te":"Noun","tt":"İsim","de":"A sudden and complete change in a country's government; or a movement in a circle","dt":"Bir ülke hükümetinde ani ve tam değişim; veya bir daire içindeki hareket","e1":"The French Revolution.","e1t":"Fransız İhtilali.","e2":"The Earth's revolution around the sun.","e2t":"Dünya'nın güneş etrafındaki dönüşü."},{"w":"revolve","tr":"dönmek / etrafında dönmek / devretmek","te":"Verb","tt":"Fiil","de":"To move in a circle around a central point","dt":"Merkezi bir nokta etrafında daire çizerek hareket etmek","e1":"The Earth revolves around the sun.","e1t":"Dünya güneşin etrafında döner.","e2":"The conversation revolved around politics.","e2t":"Konuşma siyaset etrafında döndü (siyaset odaklıydı)."},{"w":"reward","tr":"ödül / ödüllendirmek / mükafat","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something given in exchange for good work or help","dt":"İyi bir iş veya yardım karşılığında verilen şey","e1":"He received a reward for finding the lost dog.","e1t":"Kayıp köpeği bulduğu için ödül aldı.","e2":"To reward someone for their hard work.","e2t":"Birini sıkı çalışması için ödüllendirmek."},{"w":"rhetoric","tr":"hitabet / etkili konuşma sanatı / tumturaklı söz","te":"Noun","tt":"İsim","de":"The art of effective or persuasive speaking; or empty talk","dt":"Etkili veya ikna edici konuşma sanatı; veya boş/tumturaklı konuşma","e1":"Powerful political rhetoric.","e1t":"Güçlü siyasi hitabet.","e2":"Just empty rhetoric.","e2t":"Sadece boş laf."},{"w":"rhyme","tr":"kafiye / uyak / şiir","te":"Noun/Verb","tt":"İsim/Fiil","de":"A word that has the same sound as another; or to make this sound","dt":"Başka bir kelimeyle aynı sese sahip olan kelime","e1":"\"Cat\" and \"hat\" are rhymes.","e1t":"\"Cat\" ve \"hat\" kafiyelidir.","e2":"A nursery rhyme.","e2t":"Çocuk şiiri (tekerleme)."},{"w":"rhythm","tr":"ritim / tempo / düzenli akış","te":"Noun","tt":"Isim","de":"A strong, regular, repeated pattern of movement or sound","dt":"Hareket veya sesin güçlü, düzenli ve tekrarlanan deseni","e1":"To dance to the rhythm of the music.","e1t":"Müziğin ritmiyle dans etmek.","e2":"The rhythm of the seasons.","e2t":"Mevsimlerin ritmi (düzeni)."},{"w":"rib","tr":"kaburga / (giysi) fitil / şaka yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"One of the curved bones in the chest","dt":"Göğüsteki kavisli kemiklerden biri","e1":"He broke two ribs in the accident.","e1t":"Kazada iki kaburgası kırıldı.","e2":"To rib someone about their hair.","e2t":"Birinin saçıyla şakalaşmak (dalga geçmek)."},{"w":"ribbon","tr":"kurdele / şerit","te":"Noun/Verb","tt":"İsim/Fiil","de":"A narrow strip of material used for decoration","dt":"Süsleme için kullanılan dar kumaş şerit","e1":"She tied a pink ribbon in her hair.","e1t":"Saçına pembe bir kurdele bağladı.","e2":"Typewriter ribbon.","e2t":"Daktilo şeridi."},{"w":"rid","tr":"kurtulmak / başından savmak","te":"Verb/Adjective","tt":"To get rid of: to remove something unwanted","de":"İstenmeyen bir şeyi uzaklaştırmak/atmak","dt":"I want to get rid of this old sofa.","e1":"Bu eski kanepeden kurtulmak istiyorum.","e1t":"To be rid of a problem.","e2":"Bir sorundan kurtulmuş olmak.","e2t":""},{"w":"riddle","tr":"bilmece / gizem / kalburdan geçirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A difficult question that is a game; or a mystery","dt":"Oyun olan zor soru; veya gizem","e1":"To solve a riddle.","e1t":"Bir bilmeceyi çözmek.","e2":"His disappearance is a riddle.","e2t":"Onun ortadan kaybolması bir gizemdir."},{"w":"ridge","tr":"sırt (dağ) / çıkıntı / yükselti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long narrow raised part of a surface, like a mountain top","dt":"Dağ tepesi gibi, bir yüzeyin uzun dar yükseltilmiş kısmı","e1":"A mountain ridge.","e1t":"Dağ sırtı.","e2":"High pressure ridge (weather).","e2t":"Yüksek basınç sırtı."},{"w":"ridicule","tr":"alay etmek / gülünç duruma düşürmek / alay","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make someone look stupid by laughing at them","dt":"Biriyle alay ederek onu aptal durumuna düşürmek","e1":"He was ridiculed for his ideas.","e1t":"Fikirleri nedeniyle alay edildi.","e2":"To hold someone up to ridicule.","e2t":"Birini alay konusu yapmak."},{"w":"ridiculous","tr":"gülünç / saçma / absürt","te":"Adjective","tt":"Sıfat","de":"Very silly or unreasonable","dt":"Çok aptalca veya mantıksız","e1":"It's a ridiculous idea.","e1t":"Bu saçma bir fikir.","e2":"You look ridiculous in that hat.","e2t":"O şapkayla gülünç görünüyorsun."},{"w":"rifle","tr":"tüfek / tüfekle ateş etmek / (hızlıca) aramak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long gun that you hold against your shoulder","dt":"Omuzda tutulan uzun silah","e1":"An automatic rifle.","e1t":"Otomatik tüfek.","e2":"He rifled through his pockets for change.","e2t":"Bozuk para için ceplerini karıştırıp (hızlıca) aradı."},{"w":"rift","tr":"çatlak / anlaşmazlık / yarık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A serious disagreement between people; or a crack in rock","dt":"İnsanlar arasındaki ciddi anlaşmazlık; veya kayadaki çatlak","e1":"The argument caused a rift between the two friends.","e1t":"Tartışma iki arkadaş arasında bir açılmaya (anlaşmazlığa) yol açtı.","e2":"A rift in the earth's crust.","e2t":"Yer kabuğunda bir yarık."},{"w":"rigid","tr":"katı / sert / eğilmez","te":"Adjective","tt":"Sıfat","de":"Stiff and not able to be bent; or very strict","dt":"Bükülemeyen, sert; veya çok katı/kuralcı","e1":"Rigid plastic.","e1t":"Sert plastik.","e2":"A rigid hierarchy.","e2t":"Katı bir hiyerarşi."},{"w":"rigorous","tr":"titiz / sert / disiplinli","te":"Adjective","tt":"Sıfat","de":"Very careful and detailed; or strict","dt":"Çok dikkatli ve detaylı; veya sıkı","e1":"Rigorous testing.","e1t":"Titiz test süreci.","e2":"A rigorous training program.","e2t":"Sert (disiplinli) bir eğitim programı."},{"w":"rim","tr":"kenar / jant / çerçeve","te":"Noun/Verb","tt":"İsim/Fiil","de":"The outer edge of something round","dt":"Yuvarlak bir şeyin dış kenarı","e1":"The rim of a cup.","e1t":"Bir fincanın kenarı.","e2":"Wheel rims.","e2t":"Tekerlek jantları."},{"w":"riot","tr":"ayaklanma / isyan / kargaşa","te":"Noun/Verb","tt":"İsim/Fiil","de":"A noisy, violent public gathering","dt":"Gürültülü ve şiddetli toplumsal olay (ayaklanma)","e1":"Food riots broke out in the city.","e1t":"Şehirde gıda ayaklanmaları çıktı.","e2":"Riot police.","e2t":"Çevik kuvvet (isyan polisi)."},{"w":"rip","tr":"yırtmak / sökmek / yırtık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull apart or away quickly and violently","dt":"Hızla ve sertçe çekip ayırmak veya yırtmak","e1":"He ripped the letter into pieces.","e1t":"Mektubu parçalara ayırdı (yırtıp attı).","e2":"A rip in my jeans.","e2t":"Kotumda bir yırtık."},{"w":"ripe","tr":"olgun / ermiş / hazır","te":"Adjective","tt":"Sıfat","de":"(Of fruit/crops) ready to be eaten; or ready for use","dt":"(Meyve/mahsul için) yemeğe hazır; veya kullanım için hazır","e1":"Ripe tomatoes.","e1t":"Olgun domatesler.","e2":"The time is ripe for change.","e2t":"Değişim için zamanı geldi (olgunlaştı)."},{"w":"ripple","tr":"dalgalanma / hışırtı / hare","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small wave on the surface of water","dt":"Su yüzeyindeki küçük dalgacık","e1":"The stone caused ripples in the pond.","e1t":"Taş gölette dalgalanmalara neden oldu.","e2":"A ripple of laughter.","e2t":"Bir gülüşme dalgası."},{"w":"rite","tr":"ayin / tören / ritüel","te":"Noun","tt":"İsim","de":"A traditional ceremony, especially religious","dt":"Özellikle dini olan geleneksel tören","e1":"Funeral rites.","e1t":"Cenaze törenleri (ayinleri).","e2":"Rite of passage.","e2t":"Erginlenme töreni (hayatın bir evresinden diğerine geçiş)."},{"w":"ritual","tr":"ritüel / adet / geleneksel tören","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A set of fixed actions performed regularly","dt":"Düzenli olarak yapılan sabit eylemler bütünü","e1":"My morning ritual includes drinking coffee.","e1t":"Sabah ritüelim kahve içmeyi içerir.","e2":"Ritual dancing.","e2t":"Geleneksel (ayinsel) dans."},{"w":"rival","tr":"rakip / çekişmek / rakip olmak","te":"Noun/Verb/Adj","tt":"A person or thing competing with another","de":"Başkasıyla yarışan kişi veya şey","dt":"Business rivals.","e1":"Ticari rakipler.","e1t":"The two companies rival each other.","e2":"İki şirket birbiriyle çekişiyor.","e2t":""},{"w":"roar","tr":"kükremek / kükreyiş / uğultu","te":"Verb/Noun","tt":"Fiil/İsim","de":"A long, loud, deep sound","dt":"Uzun, yüksek ve derin ses","e1":"The lion gave a loud roar.","e1t":"Aslan yüksek sesle kükredi.","e2":"The roar of the engine.","e2t":"Motorun kükremesi (uğultusu)."},{"w":"roast","tr":"fırınlamak / kızartmak / kavurmak","te":"Verb/Noun/Adj","tt":"To cook food in an oven; or to heat nuts/coffee","de":"Yemeği fırında pişirmek; veya kuruyemiş/kahve ısıtmak","dt":"Roasted chicken.","e1":"Kızarmış tavuk.","e1t":"To roast coffee beans.","e2":"Kahve çekirdeklerini kavurmak.","e2t":""},{"w":"rob","tr":"soymak / çalmak / mahrum etmek","te":"Verb","tt":"Fiil","de":"To take money or property illegally from a person or place","dt":"Bir kişi veya yerden yasadışı şekilde para/mülk almak","e1":"They robbed the bank.","e1t":"Bankayı soydular.","e2":"I was robbed of my phone.","e2t":"Telefonum çalındı."},{"w":"robe","tr":"bornoz / cübbe / entari","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long, loose piece of clothing","dt":"Uzun ve bol giysi","e1":"Bath robe.","e1t":"Bornoz.","e2":"The judge wore a black robe.","e2t":"Yargıç siyah bir cübbe giydi."},{"w":"robot","tr":"robot","te":"Noun","tt":"İsim","de":"A machine controlled by a computer","dt":"Bilgisayar tarafından kontrol edilen makine","e1":"Industrial robots.","e1t":"Endüstriyel robotlar.","e2":"It works like a robot.","e2t":"Bir robot gibi çalışıyor."},{"w":"robust","tr":"sağlam / gürbüz / dirençli","te":"Adjective","tt":"Sıfat","de":"Strong and healthy; or strong in design","dt":"Güçlü ve sağlıklı; veya tasarım olarak dayanıklı","e1":"A robust economy.","e1t":"Sağlam (dirençli) bir ekonomi.","e2":"A robust young man.","e2t":"Gürbüz genç bir adam."},{"w":"rocket","tr":"roket / füze / hızla yükselmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle used for space travel; or to rise quickly","dt":"Uzay yolculuğu aracı; veya hızla yükselmek","e1":"To launch a rocket.","e1t":"Roket fırlatmak.","e2":"Prices have rocketed.","e2t":"Fiyatlar uçtu (hızla yükseldi)."},{"w":"rod","tr":"çubuk / asa / değnek","te":"Noun","tt":"İsim","de":"A long thin pole made of wood or metal","dt":"Ahşap veya metalden yapılmış uzun ince çubuk","e1":"A fishing rod.","e1t":"Balık oltası (çubuğu).","e2":"Lightning rod.","e2t":"Paratoner (yıldırım savar)."},{"w":"romance","tr":"romantizm / aşk ilişkisi / roman","te":"Noun/Verb/Adj","tt":"A story or feeling of love","de":"Aşk hikayesi veya duygusu","dt":"A summer romance.","e1":"Yaz aşkı.","e1t":"There is no romance in his life.","e2":"Hayatında romantizm yok.","e2t":""},{"w":"rooster","tr":"horoz","te":"Noun","tt":"İsim","de":"An adult male chicken","dt":"Yetişkin erkek tavuk","e1":"The rooster crows at dawn.","e1t":"Horoz şafakta öter.","e2":"A brave rooster.","e2t":"Cesur horoz."},{"w":"rose","tr":"gül / yükseldi (rise V2) / pembe","te":"Noun/Verb/Adj","tt":"A beautiful flower; or past of rise","de":"Güzel bir çiçek; veya 'rise' fiilinin geçmiş hali","dt":"A red rose.","e1":"Kırmızı gül.","e1t":"Prices rose by 10%.","e2":"Fiyatlar %10 yükseldi.","e2t":""},{"w":"rot","tr":"çürümek / çürüme / zırva","te":"Verb/Noun","tt":"Fiil/İsim","de":"To decay or go bad","dt":"Bozulmak veya çürümek","e1":"The fruit began to rot.","e1t":"Meyveler çürümeye başladı.","e2":"Don't talk rot! (don't talk nonsense).","e2t":"Zırvalama!"},{"w":"rotate","tr":"dönmek / döndürmek / sırayla yapmak","te":"Verb","tt":"Fiil","de":"To turn around a fixed point; or to take turns","dt":"Sabit bir nokta etrafında dönmek; veya dönüşümlü yapmak","e1":"The Earth rotates on its axis.","e1t":"Dünya kendi ekseni etrafında döner.","e2":"We rotate the duties every week.","e2t":"Görevleri her hafta dönüşümlü (sırayla) yapıyoruz."},{"w":"rouse","tr":"uyandırmak / harekete geçirmek / kışkırtmak","te":"Verb","tt":"Fiil","de":"To wake someone up; or to make someone active","dt":"Birini uyandırmak; veya birini harekete geçirmek","e1":"He was difficult to rouse from sleep.","e1t":"Onu uykudan uyandırmak zordu.","e2":"To rouse public opinion.","e2t":"Kamuoyunu harekete geçirmek."},{"w":"route","tr":"rota / güzergah / yol","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular way from one place to another","dt":"Bir yerden diğerine giden belirli yol","e1":"The shortest route to the airport.","e1t":"Havaalanına giden en kısa rota.","e2":"Trade routes.","e2t":"Ticaret yolları."},{"w":"rubble","tr":"moloz / yıkıntı / taş kırığı","te":"Noun","tt":"İsim","de":"Pieces of brick and stone from a destroyed building","dt":"Yıkılmış bir binadan kalan tuğla ve taş parçaları","e1":"The city was reduced to rubble.","e1t":"Şehir moloz yığınına döndü.","e2":"To search through the rubble for survivors.","e2t":"Molozlar arasında hayatta kalanları aramak."},{"w":"rug","tr":"kilim / küçük halı / battaniye","te":"Noun","tt":"İsim","de":"A piece of thick material used on a floor","dt":"Zeminde kullanılan kalın kumaş parçası","e1":"A Turkish rug.","e1t":"Türk kilimi.","e2":"To sweep something under the rug (to hide a problem).","e2t":"Bir şeyi halının altına süpürmek (sorunu gizlemek)."},{"w":"rugged","tr":"engebeli / pürüzlü / dayanıklı","te":"Adjective","tt":"Sıfat","de":"(Of land) wild and not even; or strong and tough","dt":"(Arazi için) vahşi ve düz olmayan; veya güçlü ve dayanıklı","e1":"Rugged mountains.","e1t":"Engebeli dağlar.","e2":"Rugged features (of a face).","e2t":"Sert (pürüzlü) yüz hatları."},{"w":"ruin","tr":"mahvetmek / yıkmak / kalıntı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To spoil or destroy something completely","dt":"Bir şeyi tamamen bozmak veya yok etmek","e1":"The rain ruined our picnic.","e1t":"Yağmur pikniğimizi mahvetti.","e2":"Ancient ruins of Efes.","e2t":"Efes'in antik kalıntıları."},{"w":"rumor / rumour","tr":"söylenti / şayia / duyum","te":"Noun/Verb","tt":"İsim/Fiil","de":"A story that may or may not be true","dt":"Doğru olabilen veya olmayan hikaye","e1":"There are rumors of a strike.","e1t":"Grev söylentileri var.","e2":"To spread rumors.","e2t":"Söylenti yaymak."},{"w":"rupture","tr":"yırtılmak / kopmak / fıtık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To explode or break suddenly; or a medical condition","dt":"Aniden patlamak veya kırılmak; veya tıbbi bir durum","e1":"A pipe ruptured and flooded the room.","e1t":"Bir boru patladı ve odayı su bastı.","e2":"A rupture in relations.","e2t":"İlişkilerin kopması."},{"w":"ruse","tr":"hile / oyun / tuzak","te":"Noun","tt":"İsim","de":"A clever trick used to deceive someone","dt":"Birini aldatmak için kullanılan zekice hile","e1":"It was a ruse to get him out of the house.","e1t":"Onu evden çıkarmak için bir hileydi.","e2":"A clever ruse.","e2t":"Zekice bir oyun."},{"w":"rush","tr":"acele etmek / hücum / yoğunluk","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move or do something very quickly","dt":"Çok hızlı hareket etmek veya yapmak","e1":"Don't rush me!","e1t":"Beni acele ettirme!","e2":"The morning rush hour.","e2t":"Sabahın trafik yoğunluğu saati."},{"w":"rust","tr":"pas / paslanmak / körelmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A reddish substance on iron; or to lose skill","dt":"Demir üzerindeki kızılımsı madde; veya beceri kaybetmek","e1":"The gate was covered in rust.","e1t":"Kapı pasla kaplıydı.","e2":"To rust away.","e2t":"Paslanıp gitmek."},{"w":"rustic","tr":"köye özgü / rustik / kaba","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the countryside; simple and rough","dt":"Kırsal alanla ilgili; basit ve işlenmemiş","e1":"A rustic cottage.","e1t":"Köy evi (rustik kulübe).","e2":"Rustic furniture.","e2t":"Doğal görünümlü (rustik) mobilya."},{"w":"ruthless","tr":"acımasız / merhametsiz / zalim","te":"Adjective","tt":"Sıfat","de":"Cruel and having no pity","dt":"Zalim ve hiç acıması olmayan","e1":"A ruthless dictator.","e1t":"Acımasız bir diktatör.","e2":"Ruthless competition.","e2t":"Acımasız rekabet."},{"w":"sabotage","tr":"sabote etmek / baltalamak / sabotaj","te":"Verb/Noun","tt":"Fiil/İsim","de":"To intentionally damage something to stop it working","dt":"Bir şeyin çalışmasını durdurmak için kasten zarar vermek","e1":"The equipment was sabotaged.","e1t":"Ekipman sabote edildi.","e2":"To sabotage a plan.","e2t":"Bir planı baltalamak."},{"w":"sack","tr":"çuval / işten kovmak / yağmalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large strong bag; or to fire someone","dt":"Büyük güçlü torba; veya birini işten atmak","e1":"A sack of potatoes.","e1t":"Bir çuval patates.","e2":"He got the sack (he was fired).","e2t":"Kovuldu."},{"w":"sacred","tr":"kutsal / mukaddes","te":"Adjective","tt":"Sıfat","de":"Relating to a god or religion; very important","dt":"Bir tanrı veya dinle ilgili; çok önemli","e1":"Sacred music.","e1t":"Dini (kutsal) müzik.","e2":"Cows are sacred in India.","e2t":"Hindistan'da inekler kutsaldır."},{"w":"sacrifice","tr":"fedakarlık / kurban / feda etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"To give up something valuable to help others","dt":"Başkalarına yardım etmek için değerli bir şeyi bırakmak","e1":"Parents make many sacrifices for their children.","e1t":"Ebeveynler çocukları için birçok fedakarlık yapar.","e2":"To sacrifice a career for family.","e2t":"Aile için kariyerini feda etmek."},{"w":"saddle","tr":"eyer / semer / eyerlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A leather seat for a rider on a horse or bicycle","dt":"At veya bisiklet üzerindeki deri koltuk","e1":"To put a saddle on a horse.","e1t":"Ata eyer vurmak.","e2":"Bicycle saddle.","e2t":"Bisiklet selesi."},{"w":"saga","tr":"destan / uzun hikaye / saga","te":"Noun","tt":"İsim","de":"A long complicated story about events over many years","dt":"Uzun yıllar süren olaylar hakkında karmaşık hikaye","e1":"A family saga.","e1t":"Bir aile destanı (uzun hikayesi).","e2":"The saga of the lost keys.","e2t":"Kayıp anahtarların bitmek bilmeyen hikayesi."},{"w":"sage","tr":"bilge / adaçayı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Wise; or a plant used in cooking","dt":"Bilge; veya yemeklerde kullanılan bir bitki","e1":"Sage advice.","e1t":"Bilgece tavsiye.","e2":"A sage philosopher.","e2t":"Bilge bir filozof."},{"w":"saint","tr":"aziz / çok sabırlı kişi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very holy person; or a very kind person","dt":"Çok kutsal kişi; veya çok nazik/sabırlı kişi","e1":"Saint Nicholas.","e1t":"Aziz Nikola.","e2":"You're a saint for helping me!","e2t":"Bana yardım ettiğin için bir azizsin (çok iyisin)!"},{"w":"sake","tr":"hatır / uğur / neden","te":"Noun","tt":"İsim","de":"For the purpose or benefit of someone","dt":"Birinin yararı veya hatırı için","e1":"For God's sake!","e1t":"Allah aşkına!","e2":"For the sake of the children.","e2t":"Çocukların hatırı (yararı) için."},{"w":"salient","tr":"göze çarpan / belirgin / en önemli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Most important or noticeable","dt":"En önemli veya fark edilen","e1":"The salient points of the report.","e1t":"Raporun en önemli (göze çarpan) noktaları.","e2":"Salient features.","e2t":"Belirgin özellikler."},{"w":"saliva","tr":"tükürük / salya","te":"Noun","tt":"İsim","de":"The liquid produced in your mouth","dt":"Ağızda üretilen sıvı","e1":"The smell of food made his saliva flow.","e1t":"Yemek kokusu ağzını sulandırdı (tükürük akışını sağladı).","e2":"Saliva test.","e2t":"Tükürük testi."},{"w":"salmon","tr":"somon / somon rengi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A large fish with pink meat","dt":"Pembe etli büyük balık","e1":"Grilled salmon.","e1t":"Izgara somon.","e2":"Salmon pink.","e2t":"Somon rengi (açık pembe"},{"w":"salon","tr":"salon / dükkan (güzellik vb.)","te":"Noun","tt":"İsim","de":"A shop where you can get a haircut or beauty treatment","dt":"Saç kesimi veya güzellik bakımı yaptırılan yer","e1":"Beauty salon.","e1t":"Güzellik salonu.","e2":"Hair salon.","e2t":"Kuaför salonu."},{"w":"salute","tr":"selamlamak / selam / saygı duruşu","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a formal sign of respect (especially in the military)","dt":"(Özellikle askerde) resmi bir saygı işareti yapmak","e1":"The soldiers saluted the general.","e1t":"Askerler generali selamladı.","e2":"A 21","e2t":"gun salute."},{"w":"salvage","tr":"kurtarmak (eşya) / hurda / geri kazanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To save things from a ship or a fire","dt":"Bir gemi veya yangından eşyaları kurtarmak","e1":"We managed to salvage some furniture from the fire.","e1t":"Yangından bazı mobilyaları kurtarmayı başardık.","e2":"A salvage operation.","e2t":"Kurtarma operasyonu."},{"w":"salvation","tr":"kurtuluş / selamet","te":"Noun","tt":"İsim","de":"(In religion) the state of being saved from evil; or something that saves you","dt":"(Dinde) günahtan/kötülükten kurtulma; veya birini kurtaran şey","e1":"Group therapy was his salvation.","e1t":"Grup terapisi onun kurtuluşu oldu.","e2":"The Christian message of salvation.","e2t":"Hristiyanlığın kurtuluş mesajı."},{"w":"sanction","tr":"yaptırım / onay / ambargo / onaylamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official order to stop trade; or official permission","dt":"Ticareti durdurma emri (yaptırım); veya resmi izin","e1":"Economic sanctions against the country.","e1t":"Ülkeye karşı ekonomik yaptırımlar.","e2":"The government sanctioned the project.","e2t":"Hükümet projeyi onayladı."},{"w":"sanctuary","tr":"sığınak / barınak / kutsal yer","te":"Noun","tt":"İsim","de":"A safe place; or a holy building","dt":"Güvenli yer; veya kutsal bina","e1":"A wildlife sanctuary.","e1t":"Yaban hayatı koruma alanı (barınağı).","e2":"The church offered sanctuary to the refugees.","e2t":"Kilise mültecilere sığınma imkanı sundu."},{"w":"sanitary","tr":"sıhhi / temiz / hijyenik","te":"Adjective","tt":"Sıfat","de":"Relating to public health and cleanliness","dt":"Halk sağlığı ve temizliği ile ilgili","e1":"Sanitary conditions in the camp.","e1t":"Kamptaki sıhhi koşullar.","e2":"Sanitary towels.","e2t":"Hijyenik pedler."},{"w":"sanity","tr":"akıl sağlığı / mantık","te":"Noun","tt":"İsim","de":"The state of having a healthy mind","dt":"Sağlıklı bir zihne sahip olma durumu","e1":"To keep one's sanity.","e1t":"Akıl sağlığını korumak.","e2":"A moment of sanity.","e2t":"Bir anlık mantıklı düşünme hali."},{"w":"sarcasm","tr":"iğneleme / alay / sarkazm","te":"Noun","tt":"İsim","de":"The use of remarks that mean the opposite of what they say","dt":"Söylenilenin tersini kastederek yapılan alaylı konuşma","e1":"\"Great job,\" he said with heavy sarcasm.","e1t":"\"Harika iş,\" dedi yoğun bir iğnelemeyle.","e2":"I detected a note of sarcasm in her voice.","e2t":"Sesinde bir alay tonu sezdim."},{"w":"sarcastic","tr":"iğneleyici / alaycı","te":"Adjective","tt":"Sıfat","de":"Using sarcasm to hurt or mock someone","dt":"Birini incitmek veya onunla eğlenmek için iğneleme yapan","e1":"A sarcastic comment.","e1t":"İğneleyici bir yorum.","e2":"Don't be so sarcastic!","e2t":"Bu kadar alaycı olma!"},{"w":"sardine","tr":"sardalya","te":"Noun","tt":"İsim","de":"A small silver fish often sold in cans","dt":"Genellikle konserve olarak satılan küçük gümüş balık","e1":"Packed like sardines (very crowded).","e1t":"Balık istifi gibi (çok kalabalık).","e2":"A tin of sardines.","e2t":"Bir kutu sardalya."},{"w":"satellite","tr":"uydu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A device sent into space to collect information","dt":"Bilgi toplamak için uzaya gönderilen cihaz","e1":"Satellite television.","e1t":"Uydu televizyonu.","e2":"The moon is a natural satellite of the Earth.","e2t":"Ay, Dünya'nın doğal bir uydusudur."},{"w":"satire","tr":"hiciv / yergi / taşlama","te":"Noun","tt":"İsim","de":"A way of criticizing something in a funny way","dt":"Bir şeyi komik bir yolla eleştirme biçimi","e1":"Political satire.","e1t":"Siyasi hiciv.","e2":"The play is a satire on modern life.","e2t":"Oyun modern hayat üzerine bir yergidir."},{"w":"satisfactory","tr":"tatmin edici / yeterli / uygun","te":"Adjective","tt":"Sıfat","de":"Good enough for a particular purpose","dt":"Belirli bir amaç için yeterince iyi olan","e1":"A satisfactory explanation.","e1t":"Tatmin edici (yeterli) bir açıklama.","e2":"The results were satisfactory.","e2t":"Sonuçlar tatmin ediciydi."},{"w":"saturate","tr":"doyurmak / ıslatmak / sırılsıklam etmek","te":"Verb","tt":"Fiil","de":"To make something completely wet; or to fill completely","dt":"Bir şeyi tamamen ıslatmak; veya tamamen doldurmak","e1":"The heavy rain saturated the ground.","e1t":"Şiddetli yağmur toprağı suya doyurdu (sırılsıklam etti).","e2":"Market saturation.","e2t":"Pazar doygunluğu."},{"w":"saucepan","tr":"tencere (saplı)","te":"Noun","tt":"İsim","de":"A deep metal pan with a long handle","dt":"Uzun saplı, derin metal kap","e1":"Fill the saucepan with water.","e1t":"Tencereyi suyla doldur.","e2":"To wash the saucepans.","e2t":"Tencereleri yıkamak."},{"w":"savage","tr":"vahşi / saldırgan / acımasız","te":"Adjective/Noun/Verb","tt":"Extremely violent, wild, or cruel","de":"Son derece şiddetli, vahşi veya zalim","dt":"A savage dog.","e1":"Saldırgan (vahşi) bir köpek.","e1t":"A savage attack on the government.","e2":"Hükümete yönelik acımasız bir saldırı (eleştiri).","e2t":""},{"w":"scan","tr":"taramak / göz gezdirmek / tomografi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look quickly but carefully at something","dt":"Bir şeye hızlı ama dikkatli bakmak","e1":"To scan a document.","e1t":"Bir belgeyi taramak.","e2":"To scan the headlines.","e2t":"Manşetlere göz gezdirmek."},{"w":"scandal","tr":"skandal / rezalet","te":"Noun","tt":"İsim","de":"An action or event that causes public shock and anger","dt":"Kamuoyunda şok ve öfkeye neden olan eylem veya olay","e1":"A political scandal.","e1t":"Siyasi bir skandal.","e2":"It's a scandal that...","e2t":"... olması bir rezalettir."},{"w":"scarce","tr":"kıt / nadir / az","te":"Adjective","tt":"Sıfat","de":"Not easy to find or get","dt":"Bulunması veya elde edilmesi zor olan","e1":"Food was scarce during the war.","e1t":"Savaş sırasında gıda kıttı.","e2":"Water is becoming increasingly scarce.","e2t":"Su giderek daha nadir (kıt) hale geliyor."},{"w":"scarcity","tr":"kıtlık / darlık","te":"Noun","tt":"İsim","de":"A situation in which something is not easy to find","dt":"Bir şeyin bulunmasının zor olduğu durum","e1":"The scarcity of skilled workers.","e1t":"Kalifiye işçi kıtlığı.","e2":"Scarcity of resources.","e2t":"Kaynakların yetersizliği (kıtlığı)."},{"w":"scare","tr":"korkutmak / korku / panik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make someone afraid","dt":"Birini korkutmak","e1":"You scared me!","e1t":"Beni korkuttun!","e2":"A bomb scare.","e2t":"Bomba paniği."},{"w":"scarlet","tr":"al / parlak kırmızı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"A bright red color","dt":"Parlak kırmızı renk","e1":"Her face turned scarlet with embarrassment.","e1t":"Utancından yüzü kıpkırmızı (al al) oldu.","e2":"Scarlet fever.","e2t":"Kızıl hastalığı."},{"w":"scatter","tr":"dağıtmak / saçmak / dağılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To throw things in different directions; or to move apart","dt":"Şeyleri farklı yönlere atmak; veya birbirinden uzaklaşmak","e1":"To scatter seeds in the garden.","e1t":"Bahçeye tohum saçmak.","e2":"The crowd scattered when the police arrived.","e2t":"Polis gelince kalabalık dağıldı."},{"w":"scavenge","tr":"(leş/çöp) karıştırmak / temizlemek","te":"Verb","tt":"Fiil","de":"To search through waste for things that can be used or eaten","dt":"Kullanılabilecek veya yenebilecek şeyler için atıkları karıştırmak","e1":"Rats scavenge for food.","e1t":"Fareler yiyecek için çöpleri karıştırır.","e2":"Scavenger hunt.","e2t":"Define avı (ipuçlarını takip ederek nesne bulma oyunu)."},{"w":"scenery","tr":"manzara / dekor","te":"Noun","tt":"İsim","de":"The general appearance of natural surroundings","dt":"Doğal çevrenin genel görünümü","e1":"Beautiful mountain scenery.","e1t":"Güzel dağ manzarası.","e2":"To admire the scenery.","e2t":"Manzaraya hayran kalmak."},{"w":"scent","tr":"koku / koku almak / parfüm","te":"Noun/Verb","tt":"İsim/Fiil","de":"A pleasant smell; or the smell of an animal","dt":"Hoş bir koku; veya bir hayvanın kokusu (izi)","e1":"The scent of roses.","e1t":"Güllerin kokusu.","e2":"The dog picked up the scent.","e2t":"Köpek kokuyu (izi) aldı."},{"w":"scepter / sceptre","tr":"asa (hükümdarlık)","te":"Noun","tt":"İsim","de":"A decorated stick carried by a king or queen","dt":"Kral veya kraliçe tarafından taşınan süslü asa","e1":"The king held the scepter in his hand.","e1t":"Kral asayı elinde tutuyordu.","e2":"Symbols of royal power.","e2t":"Kraliyet gücünün sembolleri."},{"w":"schedule","tr":"program / takvim / çizelge / planlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A list of planned activities or times","dt":"Planlanmış faaliyetler veya zamanlar listesi","e1":"According to the schedule.","e1t":"Programa göre.","e2":"Busy schedule.","e2t":"Yoğun program."},{"w":"scheme","tr":"plan / proje / entrika / tasarlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An organized plan for doing something, especially a dishonest one","dt":"Bir şey yapmak için organize edilmiş plan, özellikle dürüst olmayan","e1":"A pension scheme.","e1t":"Emeklilik planı (sistemi).","e2":"A clever scheme to make money.","e2t":"Para kazanmak için zekice bir plan."},{"w":"scholar","tr":"bilgin / alim / bursiyer","te":"Noun","tt":"İsim","de":"A person with great knowledge; or someone with a scholarship","dt":"Büyük bilgi sahibi kişi; veya burslu öğrenci","e1":"A Shakespeare scholar.","e1t":"Shakespeare uzmanı (bilgini).","e2":"He is a Rhodes scholar.","e2t":"Rhodes bursiyeridir."},{"w":"scholarship","tr":"burs / ilim / akademik çalışma","te":"Noun","tt":"İsim","de":"Money given to a student to pay for studies; or serious study","dt":"Eğitim masrafları için öğrenciye verilen para; veya ciddi çalışma","e1":"To win a scholarship to Oxford.","e1t":"Oxford'dan burs kazanmak.","e2":"A work of great scholarship.","e2t":"Büyük bir akademik çalışma (ilim) eseri."},{"w":"scold","tr":"azarlamak / fırça atmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak angrily to someone because they did something wrong","dt":"Yanlış bir şey yaptığı için birine öfkeyle konuşmak","e1":"His mother scolded him for breaking the vase.","e1t":"Annesi vazoyu kırdığı için onu azarladı.","e2":"To get a scolding.","e2t":"Azar işitmek."},{"w":"scoop","tr":"kepçe / dondurma topu / atlatma haber / kepçeyle almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool like a large spoon; or an exciting news story","dt":"Büyük kaşık gibi bir alet; veya heyecan verici haber","e1":"Two scoops of vanilla ice cream.","e1t":"İki top vanilyalı dondurma.","e2":"The newspaper got a major scoop.","e2t":"Gazete büyük bir atlatma haber yakaladı."},{"w":"scope","tr":"kapsam / alan / fırsat","te":"Noun/Verb","tt":"İsim/Fiil","de":"The range of a subject or activity; or opportunity","dt":"Bir konunun veya faaliyetin kapsamı; veya fırsat","e1":"This is outside the scope of our study.","e1t":"Bu, çalışmamızın kapsamı dışındadır.","e2":"There is limited scope for improvement.","e2t":"İyileştirme için sınırlı bir alan (fırsat) var."},{"w":"scorch","tr":"yakmak / kavurmak / hafifçe yanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To burn the surface of something","dt":"Bir şeyin yüzeyini yakmak","e1":"The iron scorched the shirt.","e1t":"Ütü gömleği yaktı (sararttı).","e2":"Scorching hot weather.","e2t":"Kavurucu sıcak hava."},{"w":"score","tr":"puan / skor / yirmi / beste / notalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The number of points in a game; or a set of twenty; or music","dt":"Oyundaki puan; veya yirmi adetlik set; veya müzik notası","e1":"What's the score?","e1t":"Skor kaç?","e2":"A score of people (twenty people).","e2t":"Yirmi kişi."},{"w":"scorn","tr":"küçümsemek / hor görmek / nefret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling of lack of respect for someone","dt":"Birine karşı duyulan güçlü saygısızlık (küçümseme) hissi","e1":"He treated their suggestions with scorn.","e1t":"Onların önerilerini küçümseyerek karşıladı.","e2":"To scorn someone's advice.","e2t":"Birinin tavsiyesini hor görmek."},{"w":"scorpion","tr":"akrep","te":"Noun","tt":"İsim","de":"A small creature with a poisonous sting in its tail","dt":"Kuyruğunda zehirli bir iğnesi olan küçük canlı","e1":"He was stung by a scorpion.","e1t":"Onu bir akrep soktu.","e2":"Scorpion's venom.","e2t":"Akrep zehri."},{"w":"scour","tr":"ovmak / fırçalamak / (her yeri) aramak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To clean something by rubbing it hard; or to search thoroughly","dt":"Sertçe ovarak temizlemek; veya derinlemesine aramak","e1":"I scoured the pans.","e1t":"Tencereleri ovaladım.","e2":"Police scoured the woods for the missing child.","e2t":"Polis kayıp çocuğu bulmak için ormanı didik didik aradı."},{"w":"scourge","tr":"bela / felaket / kırbaç / cezalandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that causes great suffering or trouble","dt":"Büyük acı veya soruna neden olan şey","e1":"The scourge of war.","e1t":"Savaş belası.","e2":"Poverty is a scourge on society.","e2t":"Yoksulluk toplumun üzerine bir beladır."},{"w":"scout","tr":"izci / yetenek avcısı / keşif yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person sent out to get information; or to look for someone","dt":"Bilgi almak için gönderilen kişi; veya birini aramak","e1":"A talent scout.","e1t":"Yetenek avcısı.","e2":"To scout out a location.","e2t":"Bir yeri keşfetmek (incelemek)."},{"w":"scramble","tr":"tırmanmak / çabalamak / karıştırmak (yumurta) / (mesaj) şifrelemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move quickly using your hands and feet; or to mix","dt":"El ve ayakları kullanarak hızla ilerlemek; veya karıştırmak","e1":"We scrambled up the hill.","e1t":"Tepeye tırmandık (emekleyerek/hızla).","e2":"Scrambled eggs.","e2t":"Çırpılmış (karıştırılmış) yumurta."},{"w":"scrap","tr":"hurda / parça / kırıntı / kavga / ıskartaya çıkarmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of something; or old metal","dt":"Bir şeyin küçük parçası; veya eski metal","e1":"A scrap of paper.","e1t":"Bir kağıt parçası.","e2":"To sell a car for scrap.","e2t":"Bir arabayı hurdaya satmak."},{"w":"scrape","tr":"kazımak / sürtmek / zorla başarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove something from a surface by rubbing","dt":"Bir yüzeyi sürterek bir şeyi temizlemek","e1":"I scraped the ice off the windshield.","e1t":"Ön camdaki buzu kazıdım.","e2":"He scraped his knee.","e2t":"Dizini sürttü (sıydı)."},{"w":"scratch","tr":"kaşımak / çizik / sıfır / karalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To rub your skin with your nails; or to make a thin mark","dt":"Tırnaklarla cildi ovmak; veya ince bir iz (çizik) yapmak","e1":"The cat scratched me.","e1t":"Kedi beni tırmaladı.","e2":"A scratch on the car.","e2t":"Arabada bir çizik."},{"w":"scream","tr":"çığlık atmak / bağırmak / çığlık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cry out loudly because of fear or pain","dt":"Korku veya acıyla yüksek sesle bağırmak","e1":"She screamed when she saw the spider.","e1t":"Örümceği görünce çığlık attı.","e2":"To scream for help.","e2t":"Yardım için bağırmak."},{"w":"screen","tr":"ekran / perde / elemek / incelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The flat surface of a TV or computer; or to test","dt":"TV veya bilgisayarın düz yüzeyi; veya test etmek/elemek","e1":"Computer screen.","e1t":"Bilgisayar ekranı.","e2":"To screen candidates for a job.","e2t":"İş için adayları elemek (incelemek)."},{"w":"screw","tr":"vida / vidalamak / çevirmek / kazıklamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin pointed piece of metal with a raised edge","dt":"Çıkıntılı kenarı olan ince uçlu metal parça","e1":"Tighten the screw.","e1t":"Vidayı sıkıştır.","e2":"To screw the lid on.","e2t":"Kapağı çevirerek kapatmak (vidalamak)."},{"w":"screwdriver","tr":"tornavida","te":"Noun","tt":"İsim","de":"A tool for turning screws","dt":"Vidaları çevirmek için kullanılan alet","e1":"Use a flat","e1t":"head screwdriver.","e2":"Düz uçlu tornavida kullan.","e2t":"Phillips screwdriver (cross"},{"w":"scribble","tr":"karalamak / alelacele yazmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To write or draw something quickly or carelessly","dt":"Hızlıca veya dikkatsizce yazmak/çizmek","e1":"He scribbled a note on a piece of paper.","e1t":"Bir kağıt parçasına alelacele bir not karaladı.","e2":"The child's scribbles.","e2t":"Çocuğun karalamaları."},{"w":"script","tr":"senaryo / el yazısı / alfabe / yazılı metin","te":"Noun/Verb","tt":"İsim/Fiil","de":"The written text of a play or movie; or a set of letters","dt":"Bir oyun veya filmin yazılı metni; veya bir harf kümesi","e1":"The actors are reading their scripts.","e1t":"Oyuncular senaryolarını okuyorlar.","e2":"Arabic script.","e2t":"Arap alfabesi (yazısı)."},{"w":"scrutiny","tr":"dikkatli inceleme / denetleme / tetkik","te":"Noun","tt":"İsim","de":"Careful and detailed examination","dt":"Dikkatli ve detaylı inceleme","e1":"The government's actions are under close scrutiny.","e1t":"Hükümetin eylemleri sıkı denetim (inceleme) altında.","e2":"To subject something to scrutiny.","e2t":"Bir şeyi incelemeye tabi tutmak."},{"w":"scuba","tr":"tüplü dalış ekipmanı / skuba","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Equipment used for breathing underwater","dt":"Suyun altında nefes almak için kullanılan ekipman","e1":"Scuba diving is my favorite hobby.","e1t":"Tüplü dalış en sevdiğim hobimdir.","e2":"Scuba gear.","e2t":"Dalış takımı."},{"w":"sculpt","tr":"yontmak / şekil vermek / heykel yapmak","te":"Verb","tt":"Fiil","de":"To create a solid object from a material like stone","dt":"Taş gibi bir malzemeden katı bir nesne oluşturmak","e1":"He sculpted a head out of clay.","e1t":"Kilden bir kafa yonttu (şekillendirdi).","e2":"To sculpt a beautiful body.","e2t":"Güzel bir vücut şekillendirmek."},{"w":"sculpture","tr":"heykel / heykel tıraşlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of art made by carving or shaping","dt":"Oyma veya şekillendirme ile yapılan sanat eseri","e1":"A bronze sculpture.","e1t":"Bronz bir heykel.","e2":"Modern sculpture.","e2t":"Modern heykel sanatı."},{"w":"seal","tr":"mühürlemek / kapatmak / fok balığı / mühür","te":"Noun/Verb","tt":"İsim/Fiil","de":"To close something tightly; or a sea animal","dt":"Bir şeyi sıkıca kapatmak; veya bir deniz hayvanı","e1":"To seal an envelope.","e1t":"Bir zarfı mühürlemek (kapatmak).","e2":"The cracks were sealed with silicone.","e2t":"Çatlaklar silikonla kapatıldı."},{"w":"seam","tr":"dikiş yeri / ek yeri / damar (maden)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line where two pieces of cloth are joined","dt":"İki kumaş parçasının birleştiği çizgi","e1":"The seam of his trousers ripped.","e1t":"Pantolonunun dikiş yeri yırtıldı.","e2":"A coal seam.","e2t":"Kömür damarı."},{"w":"seaport","tr":"liman kenti","te":"Noun","tt":"İsim","de":"A town or city with a harbor for sea","dt":"going ships","e1":"Deniz gemileri için limanı olan kasaba veya şehir","e1t":"Rotterdam is a major European seaport.","e2":"Rotterdam önemli bir Avrupa liman kentidir.","e2t":"A busy seaport."},{"w":"seasonal","tr":"mevsimlik / mevsime göre","te":"Adjective","tt":"Sıfat","de":"Relating to or happening during a particular season","dt":"Belirli bir mevsimle ilgili veya o mevsimde gerçekleşen","e1":"Seasonal fruit.","e1t":"Mevsim meyvesi.","e2":"Seasonal work.","e2t":"Mevsimlik iş."},{"w":"secluded","tr":"gözlerden uzak / kuytu / ıssız","te":"Adjective","tt":"Sıfat","de":"Quiet and private; away from people","dt":"Sessiz ve özel; insanlardan uzak","e1":"A secluded beach.","e1t":"Gözlerden uzak (kuytu) bir plaj.","e2":"To lead a secluded life.","e2t":"İzole (sessiz) bir hayat sürmek."},{"w":"secondary","tr":"ikincil / ortaokul / yan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Less important than something else; or relating to school for ages 11","dt":"18","e1":"Başka bir şeyden daha az önemli; veya 11","e1t":"18 yaş arası okul ile ilgili","e2":"A secondary issue.","e2t":"İkincil bir mesele."},{"w":"secretarial","tr":"sekreterlik ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the work of a secretary","dt":"Bir sekreterin işiyle ilgili","e1":"Secretarial skills.","e1t":"Sekreterlik becerileri.","e2":"To do secretarial work.","e2t":"Sekreterlik işi yapmak."},{"w":"secretary","tr":"sekreter / bakan (ABD) / yazman","te":"Noun","tt":"İsim","de":"A person who works in an office; or a high government official","dt":"Ofiste çalışan kişi; veya üst düzey hükümet görevlisi","e1":"She is the secretary to the director.","e1t":"O, müdürün sekreteridir.","e2":"Secretary of State (US).","e2t":"Dışişleri Bakanı (ABD)."},{"w":"sect","tr":"tarikat / mezhep / grup","te":"Noun","tt":"İsim","de":"A small religious group that has separated from a larger one","dt":"Daha büyük bir gruptan ayrılmış küçük dini grup","e1":"A religious sect.","e1t":"Dini bir tarikat (mezhep).","e2":"Conflicts between different sects.","e2t":"Farklı mezhepler arasındaki çatışmalar."},{"w":"section","tr":"bölüm / kısım / kesit / ayırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"One of the parts that something is divided into","dt":"Bir şeyin bölündüğü parçalardan biri","e1":"The business section of the newspaper.","e1t":"Gazetenin iş dünyası bölümü.","e2":"A cross","e2t":"section."},{"w":"sector","tr":"sektör / kesim / dilim","te":"Noun","tt":"İsim","de":"A particular part of a country's business or activity","dt":"Bir ülkenin ticari faaliyetinin veya etkinliğinin belirli bir parçası","e1":"The private sector.","e1t":"Özel sektör.","e2":"The manufacturing sector.","e2t":"İmalat sektörü."},{"w":"secular","tr":"laik / dünyevi / din dışı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not relating to religion or spiritual matters","dt":"Din veya ruhani meselelerle ilgili olmayan","e1":"A secular state.","e1t":"Laik bir devlet.","e2":"Secular music.","e2t":"Din dışı (ladini) müzik."},{"w":"secure","tr":"güvenli / sağlam / korumak / elde etmek","te":"Adjective/Verb","tt":"Safe from danger; or to make something safe","de":"Tehlikeden uzak; veya bir şeyi güvenli hale getirmek","dt":"A secure building.","e1":"Güvenli bir bina.","e1t":"To secure a loan.","e2":"Kredi temin etmek (garantilemek).","e2t":""},{"w":"sediment","tr":"tortu / çökelti","te":"Noun/Verb","tt":"İsim/Fiil","de":"Solid material that settles at the bottom of a liquid","dt":"Bir sıvının dibine çöken katı madde","e1":"There was some sediment at the bottom of the bottle.","e1t":"Şişenin dibinde biraz tortu (çökelti) vardı.","e2":"Sedimentary rock.","e2t":"Tortul kayaç."},{"w":"seed","tr":"tohum / çekirdek / seribaşı (spor) / ekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The small part of a plant from which a new plant grows","dt":"Yeni bir bitkinin yetiştiği küçük bitki parçası","e1":"To plant seeds.","e1t":"Tohum ekmek.","e2":"Sunflower seeds.","e2t":"Ayçekirdeği."},{"w":"seemingly","tr":"görünüşe bakılırsa / görünürde","te":"Adverb","tt":"Zarf","de":"Appearing to be something, even if it is not true","dt":"Doğru olmasa bile öyle görünerek","e1":"A seemingly simple task.","e1t":"Görünürde basit bir görev.","e2":"Seemingly, he has changed his mind.","e2t":"Görünüşe göre fikrini değiştirmiş."},{"w":"segment","tr":"segment / dilim / parça / bölmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"One of the parts into which something is divided","dt":"Bir şeyin bölündüğü parçalardan biri","e1":"A market segment.","e1t":"Pazar segmenti (kesimi).","e2":"An orange segment.","e2t":"Portakal dilimi."},{"w":"segregate","tr":"ayırmak / ırk ayrımı yapmak / tecrit etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep one group of people apart from another","dt":"Bir grubu diğerinden ayrı tutmak","e1":"To segregate schools by gender.","e1t":"Okulları cinsiyete göre ayırmak.","e2":"Racial segregation.","e2t":"Irk ayrımı."},{"w":"seismic","tr":"sismik / depremle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to earthquakes","dt":"Depremlerle ilgili","e1":"Seismic waves.","e1t":"Sismik dalgalar.","e2":"A seismic shift in politics.","e2t":"Siyasette sismik (çok büyük) bir değişim."},{"w":"seldom","tr":"nadiren / seyrek","te":"Adverb","tt":"Zarf","de":"Not often","dt":"Sık olmayan","e1":"He seldom goes out at night.","e1t":"Geceleri nadiren dışarı çıkar.","e2":"Seldom have I seen such beauty.","e2t":"Nadiren böyle bir güzellik gördüm."},{"w":"selective","tr":"seçici","te":"Adjective","tt":"Sıfat","de":"Careful in choosing; or affecting only some things","dt":"Seçimde dikkatli; veya sadece bazı şeyleri etkileyen","e1":"He is very selective about the books he reads.","e1t":"Okuduğu kitaplar konusunda çok seçicidir.","e2":"Selective memory.","e2t":"Seçici hafıza."},{"w":"self","tr":"esteem","te":"özsaygı / kendine güven","tt":"Noun","de":"İsim","dt":"Confidence in your own worth or abilities","e1":"Kendi değerine veya yeteneklerine olan güven","e1t":"High self","e2":"esteem.","e2t":"Yüksek özsaygı."},{"w":"semester","tr":"dönem / sömestir","te":"Noun","tt":"İsim","de":"One of the two periods that the school year is divided into","dt":"Okul yılının bölündüğü iki dönemden biri","e1":"The spring semester.","e1t":"Bahar dönemi.","e2":"At the end of the semester.","e2t":"Dönem sonunda."},{"w":"semiconductor","tr":"yarı iletken","te":"Noun","tt":"İsim","de":"A material that allows electricity to move through it only under certain conditions","dt":"Elektriğin sadece belirli koşullar altında geçmesine izin veren madde","e1":"Silicon is a semiconductor.","e1t":"Silikon bir yarı iletkendir.","e2":"The semiconductor industry.","e2t":"Yarı iletken endüstrisi."},{"w":"seminar","tr":"seminer / grup çalışması","te":"Noun","tt":"İsim","de":"A meeting of a small group of people for discussion","dt":"Tartışma için toplanan küçük insan grubu","e1":"To attend a seminar on marketing.","e1t":"Pazarlama üzerine bir seminere katılmak.","e2":"University seminar.","e2t":"Üniversite semineri."},{"w":"senate","tr":"senato","te":"Noun","tt":"İsim","de":"One of the two groups of politicians in some countries","dt":"Bazı ülkelerdeki iki siyasi gruptan biri","e1":"The US Senate.","e1t":"ABD Senatosu.","e2":"A member of the senate.","e2t":"Senatör."},{"w":"sensation","tr":"duygu / his / sansasyon / heyecan","te":"Noun","tt":"İsim","de":"A physical feeling; or a cause of great excitement","dt":"Fiziksel his; veya büyük heyecan nedeni","e1":"A tingling sensation.","e1t":"Karıncalanma hissi.","e2":"The book caused a sensation.","e2t":"Kitap sansasyon yarattı."},{"w":"sensational","tr":"sansasyonel / şahane / hayret verici","te":"Adjective","tt":"Sıfat","de":"Very exciting or shocking; or very good","dt":"Çok heyecan verici veya şok edici; veya çok iyi","e1":"Sensational news.","e1t":"Sansasyonel (şok edici) haberler.","e2":"You look sensational!","e2t":"Şahane görünüyorsun!"},{"w":"sensibility","tr":"duyarlılık / hassasiyet / sağduyu","te":"Noun","tt":"İsim","de":"The ability to feel or understand something","dt":"Bir şeyi hissetme veya anlama yeteneği","e1":"Artistic sensibility.","e1t":"Sanatsal duyarlılık.","e2":"To offend someone's sensibilities.","e2t":"Birinin hassasiyetlerini (duygularını) incitmek."},{"w":"sentimental","tr":"duygusal / aşırı hassas / hisli","te":"Adjective","tt":"Sıfat","de":"Relating to emotions rather than reason","dt":"Mantıktan ziyade duygularla ilgili","e1":"The ring has sentimental value.","e1t":"Yüzüğün manevi (duygusal) değeri var.","e2":"Don't be so sentimental.","e2t":"Bu kadar duygusal olma."},{"w":"separate","tr":"ayrı / müstakil / ayırmak / bölünmek","te":"Adjective/Verb/Noun","tt":"Existing as a different unit; or to move apart","de":"Farklı bir birim olarak var olan; veya birbirinden uzaklaşmak","dt":"We have separate rooms.","e1":"Ayrı odalarımız var.","e1t":"To separate the wheat from the chaff.","e2":"İyiyi kötüden ayırmak (sapla samanı ayırmak).","e2t":""},{"w":"sequence","tr":"dizi / sıra / silsile / sıralamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular order in which things follow each other","dt":"Şeylerin birbirini takip ettiği belirli düzen","e1":"A sequence of events.","e1t":"Olaylar dizisi (silsilesi).","e2":"In the correct sequence.","e2t":"Doğru sırada."},{"w":"serene","tr":"huzurlu / sakin / dingin","te":"Adjective","tt":"Sıfat","de":"Peaceful and calm","dt":"Barışçıl ve sakin","e1":"A serene mountain landscape.","e1t":"Huzurlu bir dağ manzarası.","e2":"She looked very serene.","e2t":"Çok dingin (sakin) görünüyordu."},{"w":"serenity","tr":"huzur / dinginlik / sükunet","te":"Noun","tt":"İsim","de":"The quality of being peaceful and calm","dt":"Barışçıl ve sakin olma niteliği","e1":"The serenity of the forest.","e1t":"Ormanın huzuru.","e2":"To find inner serenity.","e2t":"İç huzuru bulmak."},{"w":"series","tr":"dizi / seri / silsile","te":"Noun","tt":"İsim","de":"A number of similar things coming one after another","dt":"Birbiri ardına gelen benzer şeyler","e1":"A television series.","e1t":"Televizyon dizisi.","e2":"A series of meetings.","e2t":"Bir dizi toplantı."},{"w":"sermon","tr":"vaaz / nasihat","te":"Noun/Verb","tt":"İsim/Fiil","de":"A talk on a religious or moral subject","dt":"Dini veya ahlaki bir konu üzerine konuşma","e1":"The priest gave a powerful sermon.","e1t":"Rahip etkileyici bir vaaz verdi.","e2":"Don't give me a sermon!","e2t":"Bana nasihat verme!"},{"w":"serpent","tr":"yılan (büyük) / ejderha","te":"Noun","tt":"İsim","de":"A large snake (literary or formal)","dt":"Büyük yılan (edebi veya resmi)","e1":"The serpent in the Garden of Eden.","e1t":"Aden Bahçesi'ndeki yılan.","e2":"Sea serpent.","e2t":"Deniz yılanı (canavarı)."},{"w":"servant","tr":"hizmetçi / uşak / hizmetkar","te":"Noun","tt":"İsim","de":"A person who is employed in another person's house","dt":"Başka birinin evinde çalışan kişi","e1":"A domestic servant.","e1t":"Ev hizmetçisi.","e2":"Civil servant (government worker).","e2t":"Devlet memuru."},{"w":"setback","tr":"aksilik / gerileme / engel","te":"Noun","tt":"İsim","de":"A problem that delays or stops progress","dt":"İlerlemeyi geciktiren veya durduran sorun","e1":"The project suffered a major setback.","e1t":"Proje büyük bir aksilik (gerileme) yaşadı.","e2":"To overcome a setback.","e2t":"Bir engeli aşmak."},{"w":"sever","tr":"kesmek / ayırmak / (bağı) koparmak","te":"Verb","tt":"Fiil","de":"To break or separate something completely","dt":"Bir şeyi tamamen kırmak veya ayırmak","e1":"To sever a limb.","e1t":"Bir uzvu kesmek (koparmak).","e2":"The two countries severed diplomatic relations.","e2t":"İki ülke diplomatik ilişkileri kesti."},{"w":"severe","tr":"şiddetli / sert / ağır","te":"Adjective","tt":"Sıfat","de":"Very serious or extreme","dt":"Çok ciddi veya aşırı","e1":"Severe pain.","e1t":"Şiddetli ağrı.","e2":"Severe winter.","e2t":"Sert kış."},{"w":"sewer","tr":"lağım / kanalizasyon","te":"Noun/Verb","tt":"İsim/Fiil","de":"An underground pipe that carries away waste water","dt":"Atık suyu taşıyan yer altı borusu","e1":"The city's sewer system.","e1t":"Şehrin kanalizasyon sistemi.","e2":"Open sewer.","e2t":"Açık lağım."},{"w":"shabby","tr":"eski püskü / perişan / hırpani","te":"Adjective","tt":"Sıfat","de":"Looking old and in bad condition","dt":"Eski ve kötü durumda görünen","e1":"Shabby clothes.","e1t":"Eski püskü (hırpani) giysiler.","e2":"A shabby hotel.","e2t":"Perişan (bakımsız) bir otel."},{"w":"shady","tr":"gölgeli / karanlık (işler) / şüpheli","te":"Adjective","tt":"Sıfat","de":"Protected from direct light from the sun; or dishonest","dt":"Güneşten gelen doğrudan ışıktan korunan; veya dürüst olmayan","e1":"A shady spot under a tree.","e1t":"Ağaç altında gölgeli bir yer.","e2":"Shady business deals.","e2t":"Karanlık (şüpheli) iş anlaşmaları."},{"w":"shale","tr":"şeyl / killi mika / yapraklı kaya","te":"Noun","tt":"İsim","de":"A type of soft rock that splits easily into thin layers","dt":"İnce tabakalara kolayca ayrılan bir tür yumuşak kaya","e1":"Shale oil.","e1t":"Şeyl yağı (kaya petrolü).","e2":"Deposits of shale.","e2t":"Şeyl yatakları."},{"w":"shallow","tr":"sığ / yüzeyel / sığ düşünceli","te":"Adjective/Noun/Verb","tt":"Not deep; or not showing serious thought","de":"Derin olmayan; veya ciddi bir düşünce göstermeyen","dt":"The water is quite shallow here.","e1":"Su burada oldukça sığdır.","e1t":"A shallow person.","e2":"Yüzeysel (sığ) bir kişi.","e2t":""},{"w":"shatter","tr":"paramparça etmek / tuzla buz olmak / yıkılmak (umut)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To break suddenly into very small pieces","dt":"Aniden çok küçük parçalara ayrılmak","e1":"The glass shattered into a thousand pieces.","e1t":"Cam bin parçaya bölündü (tuzla buz oldu).","e2":"The news shattered her hopes.","e2t":"Haberler onun umutlarını yıktı (parçaladı)."},{"w":"sheer","tr":"saf / dikey / şeffaf (kumaş) / sapmak","te":"Adjective/Adv/Verb","tt":"Used to emphasize size or amount; or very steep","de":"Boyut veya miktarı vurgulamak için kullanılır (saf/tam); veya çok dik","dt":"It was a sheer miracle that they survived.","e1":"Hayatta kalmaları tam (saf) bir mucizeydi.","e1t":"A sheer cliff.","e2":"Dik bir uçurum.","e2t":""},{"w":"shellfish","tr":"kabuklu deniz hayvanı","te":"Noun","tt":"İsim","de":"Edible sea creatures with a shell, like lobsters or mussels","dt":"İstakoz veya midye gibi kabuklu yenilebilir deniz canlıları","e1":"Some people are allergic to shellfish.","e1t":"Bazı insanların kabuklu deniz ürünlerine alerjisi vardır.","e2":"Fresh shellfish.","e2t":"Taze kabuklu deniz ürünü."},{"w":"shelter","tr":"barınak / sığınak / korumak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A building or place that provides protection","dt":"Koruma sağlayan bina veya yer","e1":"To find shelter from the rain.","e1t":"Yağmurdan kaçacak bir barınak bulmak.","e2":"Animal shelter.","e2t":"Hayvan barınağı."},{"w":"shield","tr":"kalkan / korumak / muhafaza","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large flat object used for protection; or to protect","dt":"Korunma için kullanılan geniş düz nesne; veya korumak","e1":"The police used shields against the stones.","e1t":"Polis taşlara karşı kalkan kullandı.","e2":"To shield your eyes from the sun.","e2t":"Gözlerini güneşten korumak (perdelemek)."},{"w":"shift","tr":"vites / vardiya / değişim / değiştirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A change in position or direction; or a period of work","dt":"Konum veya yönde değişim; veya çalışma süresi","e1":"A shift in public opinion.","e1t":"Kamuoyu görüşünde bir kayma (değişim).","e2":"I'm working the night shift.","e2t":"Gece vardiyasında çalışıyorum."},{"w":"shipment","tr":"sevkiyat / gönderi","te":"Noun","tt":"İsim","de":"An amount of goods sent by ship, train, or plane","dt":"Gemi, tren veya uçakla gönderilen mal miktarı","e1":"The first shipment of aid arrived today.","e1t":"Yardımın ilk sevkiyatı bugün ulaştı.","e2":"To track a shipment.","e2t":"Bir sevkiyatı takip etmek."},{"w":"shiver","tr":"titremek / ürpermek / titreme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shake slightly because of cold or fear","dt":"Soğuk veya korku nedeniyle hafifçe sallanmak","e1":"He shivered with cold.","e1t":"Soğuktan titredi.","e2":"A shiver ran down her spine.","e2t":"Sırtından aşağı bir ürperti geçti."},{"w":"shortage","tr":"kıtlık / eksiklik / darlık","te":"Noun","tt":"İsim","de":"A situation in which there is not enough of something","dt":"Bir şeyin yeterli olmadığı durum","e1":"A food shortage.","e1t":"Gıda kıtlığı.","e2":"There is a shortage of skilled teachers.","e2t":"Kalifiye öğretmen eksikliği var."},{"w":"shortcoming","tr":"eksiklik / kusur / zayıf yön","te":"Noun","tt":"İsim","de":"A fault or failure to meet a certain standard","dt":"Bir hata veya belirli bir standardı karşılayamama","e1":"Despite his shortcomings, he is a good man.","e1t":"Kusurlarına rağmen iyi bir adamdır.","e2":"To identify the shortcomings of the plan.","e2t":"Planın eksikliklerini tespit etmek."},{"w":"shove","tr":"itmek / tıkıştırmak / dürtmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push someone or something forcefully","dt":"Birini veya bir şeyi güçle itmek","e1":"He shoved his way through the crowd.","e1t":"Kalabalığın arasından iterek yolunu açtı.","e2":"To shove something into a drawer.","e2t":"Bir şeyi çekmeceye tıkıştırmak."},{"w":"shovelful","tr":"bir kürek dolusu","te":"Noun","tt":"İsim","de":"The amount that a shovel can hold","dt":"Bir küreğin alabildiği miktar","e1":"Add a shovelful of coal to the fire.","e1t":"Ateşe bir kürek dolusu kömür ekle.","e2":"A shovelful of sand.","e2t":"Bir kürek dolusu kum."},{"w":"shrewd","tr":"zeki / kurnaz / açıkgöz","te":"Adjective","tt":"Sıfat","de":"Having good judgment or being clever in business","dt":"İyi bir yargıya sahip olan veya iş dünyasında zeki/kurnaz olan","e1":"A shrewd businessman.","e1t":"Kurnaz bir iş adamı.","e2":"A shrewd investment.","e2t":"Akıllıca (zeki) bir yatırım."},{"w":"shriek","tr":"çığlık atmak / feryat etmek / tiz ses","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a very high loud sound, especially in fear","dt":"Özellikle korkuyla çok yüksek ve tiz bir ses çıkarmak","e1":"She shrieked when she saw the mouse.","e1t":"Fareyi görünce çığlık attı.","e2":"To shriek with laughter.","e2t":"Kahkahalarla haykırmak."},{"w":"shrine","tr":"tapınak / türbe / kutsal yer","te":"Noun/Verb","tt":"İsim/Fiil","de":"A holy place or a place dedicated to a famous person","dt":"Kutsal bir yer veya ünlü birine adanmış yer","e1":"To visit a holy shrine.","e1t":"Kutsal bir türbeyi ziyaret etmek.","e2":"The town is a shrine to its history.","e2t":"Kasaba, tarihine adanmış bir anıt (kutsal yer) gibidir."},{"w":"shrink","tr":"küçülmek / çekmek (kumaş) / psikolog (argo)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become smaller; or to move back in fear","dt":"Küçülmek; veya korkuyla geri çekilmek","e1":"The shirt shrank in the wash.","e1t":"Gömlek yıkamada çekti (küçüldü).","e2":"The economy is expected to shrink.","e2t":"Ekonominin küçülmesi bekleniyor."},{"w":"shrub","tr":"çalı / fundalık","te":"Noun","tt":"İsim","de":"A plant like a small tree with many wooden stems","dt":"Birçok odunsu gövdesi olan küçük ağaç benzeri bitki","e1":"Evergreen shrubs.","e1t":"Her daim yeşil çalılar.","e2":"To plant shrubs in the garden.","e2t":"Bahçeye çalılar dikmek."},{"w":"shrug","tr":"omuz silkmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To raise your shoulders to show you don't know or care","dt":"Bilmediğini veya umursamadığını göstermek için omuzları kaldırmak","e1":"He just shrugged his shoulders.","e1t":"Sadece omuz silkti.","e2":"To shrug off a problem (to ignore it).","e2t":"Bir sorunu umursamamak (üzerinden atmak)."},{"w":"shudder","tr":"titremek / ürpermek / sarsılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shake suddenly with a very small movement","dt":"Çok küçük bir hareketle aniden sallanmak","e1":"I shudder to think what might have happened.","e1t":"Ne olmuş olabileceğini düşününce ürperiyorum.","e2":"The engine shuddered and stopped.","e2t":"Motor sarsıldı ve durdu."},{"w":"shun","tr":"kaçınmak / uzak durmak / dışlamak","te":"Verb","tt":"Fiil","de":"To avoid something or someone intentionally","dt":"Bir şeyden veya birinden kasten kaçınmak","e1":"He was shunned by his former friends.","e1t":"Eski arkadaşları tarafından dışlandı (uzak duruldu).","e2":"To shun publicity.","e2t":"Reklamdan (tanınırlıktan) kaçınmak."},{"w":"shutter","tr":"panjur / kepenk / deklanşör","te":"Noun/Verb","tt":"İsim/Fiil","de":"A cover for a window; or part of a camera","dt":"Pencere kapağı; veya kamera parçası","e1":"To close the shutters.","e1t":"Panjurları kapatmak.","e2":"Camera shutter speed.","e2t":"Kamera deklanşör hızı."},{"w":"shuttle","tr":"mekik / servis aracı / git gel yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle that travels regularly between two places","dt":"İki yer arasında düzenli gidip gelen araç","e1":"Space shuttle.","e1t":"Uzay mekiği.","e2":"An airport shuttle bus.","e2t":"Havaalanı servis otobüsü."},{"w":"side","tr":"effect","te":"yan etki","tt":"Noun","de":"İsim","dt":"An unwanted effect of a drug; or an unexpected result","e1":"Bir ilacın istenmeyen etkisi; veya beklenmedik sonuç","e1t":"Does this medicine have any side","e2":"effects?","e2t":"Bu ilacın herhangi bir yan etkisi var mı?"},{"w":"siege","tr":"kuşatma / muhasara","te":"Noun/Verb","tt":"İsim/Fiil","de":"The surrounding of a place by an army to force it to surrender","dt":"Bir ordunun bir yeri teslim olmaya zorlamak için etrafını sarması","e1":"The siege lasted for three months.","e1t":"Kuşatma üç ay sürdü.","e2":"To be under siege.","e2t":"Kuşatma altında olmak."},{"w":"sieve","tr":"elek / kalbur / elemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for separating solids from liquids or small from large","dt":"Katıları sıvılardan veya küçükleri büyüklerden ayırma aleti","e1":"Pass the flour through a sieve.","e1t":"Unu bir elekten geçirin.","e2":"He has a memory like a sieve (forgets easily).","e2t":"Kalbur gibi hafızası var (çabuk unutuyor)."},{"w":"sift","tr":"elemek / titizlikle incelemek / süzmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put something through a sieve; or to examine carefully","dt":"Bir şeyi elekten geçirmek; veya dikkatle incelemek","e1":"To sift through the evidence.","e1t":"Kanıtları titizlikle incelemek (ayıklamak).","e2":"Sift the sugar onto the cake.","e2t":"Şekeri kekin üzerine eleyin."},{"w":"sigh","tr":"iç çekmek / ah etmek / iç çekiş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To breathe out slowly and loudly in sadness or relief","dt":"Üzüntü veya rahatlama ile yavaşça ve sesli nefes vermek","e1":"He sighed with relief.","e1t":"Rahatlayarak iç çekti.","e2":"\"I'm so tired,\" she sighed.","e2t":"\"Çok yorgunum,\" diye iç geçirdi."},{"w":"signal","tr":"sinyal / işaret / sinyal vermek","te":"Noun/Verb/Adj","tt":"A sound or movement that gives information","de":"Bilgi veren ses veya hareket","dt":"A traffic signal.","e1":"Trafik lambası (sinyali).","e1t":"The red light is a signal to stop.","e2":"Kırmızı ışık durma işaretidir.","e2t":""},{"w":"signature","tr":"imza / ayırt edici özellik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Your name written in your own special way","dt":"Kendi özel tarzınızla yazılmış isminiz","e1":"Please put your signature here.","e1t":"Lütfen imzanızı buraya atın.","e2":"A signature dish (of a chef).","e2t":"(Şefin) ayırt edici (imza) yemeği."},{"w":"significance","tr":"önem / anlam / değer","te":"Noun","tt":"İsim","de":"The importance of something","dt":"Bir şeyin önemi","e1":"The significance of the discovery.","e1t":"Keşfin önemi.","e2":"Historical significance.","e2t":"Tarihsel önem."},{"w":"silicon","tr":"silikon / silisyum","te":"Noun","tt":"İsim","de":"A chemical element used in computer chips","dt":"Bilgisayar çiplerinde kullanılan kimyasal element","e1":"Silicon Valley.","e1t":"Silikon Vadisi.","e2":"Silicon is a semiconductor.","e2t":"Silikon bir yarı iletkendir."},{"w":"silt","tr":"alüvyon / mil / çamurla dolmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Sand or soil that is carried by flowing water","dt":"Akan suyun taşıdığı kum veya toprak","e1":"The river was filled with silt.","e1t":"Nehir mil (alüvyon) ile dolmuştu.","e2":"To silt up.","e2t":"Çamurla tıkanmak."},{"w":"silverware","tr":"gümüş eşya / çatal bıçak takımı","te":"Noun","tt":"İsim","de":"Objects made of silver, especially forks, knives, and spoons","dt":"Gümüşten yapılmış nesneler, özellikle çatal, bıçak ve kaşıklar","e1":"To polish the silverware.","e1t":"Gümüş takımları parlatmak.","e2":"Family silverware.","e2t":"Aile gümüşleri."},{"w":"simile","tr":"teşbih / benzetme","te":"Noun","tt":"İsim","de":"A phrase that describes something by comparing it with another","dt":"Bir şeyi başka bir şeyle karşılaştırarak betimleyen ifade","e1":"\"As brave as a lion\" is a simile.","e1t":"\"Aslan kadar cesur\" bir benzetmedir.","e2":"To use similes in poetry.","e2t":"Şiirde teşbihler kullanmak."},{"w":"simmer","tr":"kısık ateşte pişmek / kaynamaya başlamak / (öfke) birikmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cook something slowly at a temperature just below boiling","dt":"Kaynama noktasının hemen altındaki sıcaklıkta yavaşça pişirmek","e1":"Let the soup simmer for 20 minutes.","e1t":"Çorbanın 20 dakika kısık ateşte pişmesine izin verin.","e2":"Simmering anger.","e2t":"İçten içe yanan (biriken) öfke."},{"w":"simplify","tr":"basitleştirmek / sadeleştirmek","te":"Verb","tt":"Fiil","de":"To make something easier to understand or do","dt":"Bir şeyin anlaşılmasını veya yapılmasını kolaylaştırmak","e1":"Can you simplify the instructions?","e1t":"Talimatları basitleştirebilir misin?","e2":"To simplify a fraction (math).","e2t":"Bir kesri sadeleştirmek."},{"w":"simultaneous","tr":"eşzamanlı / aynı anda olan","te":"Adjective","tt":"Sıfat","de":"Happening or being done at exactly the same time","dt":"Tam olarak aynı zamanda olan veya yapılan","e1":"Simultaneous translation.","e1t":"Eşzamanlı (simültane) çeviri.","e2":"Simultaneous explosions.","e2t":"Aynı anda gerçekleşen patlamalar."},{"w":"sin","tr":"günah / günah işlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An act that goes against a religious or moral law","dt":"Dini veya ahlaki yasaya aykırı eylem","e1":"To commit a sin.","e1t":"Günah işlemek.","e2":"Deadly sins.","e2t":"Ölümcül günahlar."},{"w":"sincere","tr":"samimi / içten / dürüst","te":"Adjective","tt":"Sıfat","de":"Honest and saying what you really think","dt":"Dürüst ve gerçekten ne düşündüğünü söyleyen","e1":"Sincere apologies.","e1t":"İçten (samimi) özürler.","e2":"A sincere friend.","e2t":"Samimi bir arkadaş."},{"w":"sincerity","tr":"samimiyet / içtenlik","te":"Noun","tt":"İsim","de":"The quality of being honest and sincere","dt":"Dürüst ve samimi olma niteliği","e1":"I doubt his sincerity.","e1t":"Onun samimiyetinden şüphe ediyorum.","e2":"With all sincerity.","e2t":"Tüm samimiyetimle."},{"w":"singular","tr":"tekil / eşsiz / tuhaf","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to one person or thing; or unusual","dt":"Bir kişi veya şeyle ilgili; veya sıra dışı","e1":"The singular form of \"children\" is \"child\".","e1t":"\"Children\" kelimesinin tekil hali \"child\"dır.","e2":"A singular achievement.","e2t":"Eşsiz (sıra dışı) bir başarı."},{"w":"sinister","tr":"uğursuz / kötü / meşum","te":"Adjective","tt":"Sıfat","de":"Making you feel that something evil is going to happen","dt":"Kötü bir şeyin olacağını hissettiren","e1":"A sinister look.","e1t":"Uğursuz (karanlık) bir bakış.","e2":"There was something sinister about the house.","e2t":"Evde uğursuz bir şeyler vardı."},{"w":"sink","tr":"batmak / çökmek / lavabo","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go down below the surface of water; or a place to wash dishes","dt":"Suyun yüzeyinin altına inmek; veya bulaşık yıkama yeri","e1":"The ship began to sink.","e1t":"Gemi batmaya başladı.","e2":"Kitchen sink.","e2t":"Mutfak lavabosu."},{"w":"sinus","tr":"sinüs / boşluk","te":"Noun","tt":"İsim","de":"A hollow space in the bones of the face","dt":"Yüz kemiklerindeki boşluk","e1":"Sinus infection.","e1t":"Sinüzit (sinüs enfeksiyonu).","e2":"My sinuses are blocked.","e2t":"Sinüslerim tıkalı."},{"w":"sip","tr":"yudumlamak / yudum","te":"Verb/Noun","tt":"Fiil/İsim","de":"To drink something by taking very small amounts","dt":"Bir şeyi çok küçük miktarlarda içmek","e1":"She sipped her hot tea.","e1t":"Sıcak çayını yudumladı.","e2":"To take a sip of water.","e2t":"Bir yudum su almak."},{"w":"siren","tr":"siren / canavar düdüğü / cazibeli kadın","te":"Noun","tt":"İsim","de":"A device that makes a loud warning sound; or a dangerous woman","dt":"Yüksek sesli uyarı veren cihaz; veya tehlikeli (çekici) kadın","e1":"A police siren.","e1t":"Polis sireni.","e2":"Fog siren.","e2t":"Sis düdüğü."},{"w":"site","tr":"site / yer / alan / konumlandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where something is located or where an event happens","dt":"Bir şeyin bulunduğu veya bir olayın gerçekleştiği yer","e1":"Construction site.","e1t":"İnşaat alanı (sahası).","e2":"Web site.","e2t":"Web sitesi."},{"w":"skeleton","tr":"iskelet / ana hatlar","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The frame of bones supporting a human or animal body","dt":"İnsan veya hayvan vücudunu destekleyen kemik çatısı","e1":"A human skeleton.","e1t":"İnsan iskeleti.","e2":"The skeleton of a new building.","e2t":"Yeni bir binanın karkas (ana) yapısı."},{"w":"skeptic / sceptic","tr":"şüpheci / kuşkucu","te":"Noun","tt":"İsim","de":"A person who doubts that something is true","dt":"Bir şeyin doğruluğundan şüphe eden kişi","e1":"I'm a bit of a skeptic when it comes to magic.","e1t":"Büyü söz konusu olduğunda biraz şüpheciyimdir.","e2":"Climate change skeptics.","e2t":"İklim değişikliği şüphecileri."},{"w":"skeptical / sceptical","tr":"şüpheci / kuşkulu","te":"Adjective","tt":"Sıfat","de":"Doubting that something is true or useful","dt":"Bir şeyin doğru veya yararlı olduğundan şüphe duyan","e1":"I’m skeptical about his chances of winning.","e1t":"Onun kazanma şansı konusunda şüpheciyim.","e2":"A skeptical look.","e2t":"Kuşkulu bir bakış."},{"w":"sketch","tr":"taslak / skeç / karalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A simple, quickly","dt":"made drawing; or a short funny play","e1":"Basit, hızlıca yapılmış çizim; veya kısa komik oyun","e1t":"He made a quick sketch of the house.","e2":"Evin hızlıca bir taslağını (karalamasını) çizdi.","e2t":"A comedy sketch."},{"w":"skim","tr":"kaymağını almak / göz gezdirmek / (su üstünde) sektirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove something from the surface of a liquid; or to read quickly","dt":"Bir sıvının yüzeyinden bir şeyi almak; veya hızlıca okumak","e1":"Skim the fat off the soup.","e1t":"Çorbanın yağını (üstünden) al.","e2":"I skimmed the report before the meeting.","e2t":"Toplantıdan önce rapora göz gezdirdim."},{"w":"skip","tr":"atlamak / geçmek / sekmek / çöp konteyneri","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move with small jumps; or to not do something you should","dt":"Küçük adımlarla sıçrayarak ilerlemek; veya yapılması gereken bir şeyi yapmamak","e1":"I skipped breakfast this morning.","e1t":"Bu sabah kahvaltıyı atladım (yapmadım).","e2":"Skip to the next chapter.","e2t":"Bir sonraki bölüme geç."},{"w":"skull","tr":"kafatası","te":"Noun","tt":"İsim","de":"The bones of the head that surround the brain","dt":"Beyni çevreleyen baş kemikleri","e1":"He fractured his skull in the accident.","e1t":"Kazada kafatası çatladı.","e2":"Skull and crossbones (symbol of danger).","e2t":"Kurukafa ve çapraz kemikler (tehlike sembolü)."},{"w":"skyscraper","tr":"gökdelen","te":"Noun","tt":"İsim","de":"A very tall modern building","dt":"Çok yüksek modern bina","e1":"New York is famous for its skyscrapers.","e1t":"New York gökdelenleriyle ünlüdür.","e2":"To build a skyscraper.","e2t":"Gökdelen inşa etmek."},{"w":"slab","tr":"levha / blok / dilim (kalın)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thick, flat piece of a solid substance","dt":"Katı bir maddenin kalın, düz parçası","e1":"A concrete slab.","e1t":"Beton blok (levha).","e2":"A thick slab of chocolate.","e2t":"Kalın bir dilim çikolata."},{"w":"slack","tr":"gevşek / durgun / ihmalkâr / gevşetmek","te":"Adjective/Noun/Verb","tt":"Not tight; or not busy; or showing lack of effort","de":"Sıkı olmayan; veya yoğun olmayan; veya çaba eksikliği gösteren","dt":"The rope went slack.","e1":"İp gevşedi.","e1t":"Business is slack at this time of year.","e2":"Yılın bu zamanında işler durgun.","e2t":""},{"w":"slam","tr":"çarpmak / gümletmek / sertçe eleştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shut a door or lid with great force and noise","dt":"Bir kapıyı veya kapağı büyük bir güç ve gürültüyle kapatmak","e1":"Don't slam the door!","e1t":"Kapıyı çarpma!","e2":"The critics slammed the movie.","e2t":"Eleştirmenler filmi yerin dibine soktu (sertçe eleştirdi)."},{"w":"slander","tr":"iftira / iftira atmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A false spoken statement intended to damage someone's reputation","dt":"Birinin itibarını zedelemek amacıyla söylenen yalan söz","e1":"He was sued for slander.","e1t":"İftira davası açıldı.","e2":"To slander a political opponent.","e2t":"Siyasi bir rakibe iftira atmak."},{"w":"slang","tr":"argo","te":"Noun/Verb","tt":"İsim/Fiil","de":"Informal language used by a particular group","dt":"Belirli bir grup tarafından kullanılan resmi olmayan dil","e1":"Teenage slang.","e1t":"Gençlik argosu.","e2":"\"Buck\" is slang for dollar.","e2t":"\"Buck\" dolar için kullanılan bir argodur."},{"w":"slant","tr":"eğim / meyil / taraflı bakış / eğik olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To slope; or to present information in a biased way","dt":"Eğik olmak; veya bilgiyi taraflı bir şekilde sunmak","e1":"The floor slants toward the door.","e1t":"Zemin kapıya doğru eğimli.","e2":"A political slant on the news.","e2t":"Haberlere siyasi bir bakış açısı (taraflılık)."},{"w":"slap","tr":"tokat / tokatlamak / şak diye koymak","te":"Verb/Noun/Adv","tt":"To hit someone with the flat part of the hand","de":"Elin ayasıyla birine vurmak","dt":"She slapped him across the face.","e1":"Suratına bir tokat attı.","e1t":"A slap in the face (an insult).","e2":"Yüzde patlayan tokat (hakaret/şok).","e2t":""},{"w":"slaughter","tr":"kesmek (hayvan) / katletmek / katliam","te":"Noun/Verb","tt":"İsim/Fiil","de":"The killing of animals for meat; or the killing of many people","dt":"Et için hayvan kesimi; veya birçok insanın öldürülmesi","e1":"The slaughter of innocent civilians.","e1t":"Masum sivillerin katledilmesi.","e2":"Slaughterhouse.","e2t":"Mezbaha."},{"w":"slay","tr":"katletmek / canına kıymak / çok etkilemek (argo)","te":"Verb","tt":"Fiil","de":"To kill someone in a violent way","dt":"Birini şiddetli bir şekilde öldürmek","e1":"St. George slew the dragon.","e1t":"Aziz George ejderhayı katletti (öldürdü).","e2":"You slay me! (You make me laugh a lot).","e2t":"Beni öldürüyorsun (çok güldürüyorsun)."},{"w":"sleek","tr":"pürüzsüz / parlak / şık / bakımlı","te":"Adjective/Verb","tt":"Smooth, shiny, and looking healthy or expensive","de":"Pürüzsüz, parlak ve sağlıklı veya pahalı görünen","dt":"A sleek black car.","e1":"Şık (parlak) siyah bir araba.","e1t":"Sleek hair.","e2":"Bakımlı (pürüzsüz) saçlar.","e2t":""},{"w":"slender","tr":"ince / narin / kısıtlı","te":"Adjective","tt":"Sıfat","de":"Thin and attractive; or small in amount","dt":"İnce ve çekici; veya miktar olarak az","e1":"A slender young woman.","e1t":"Narin (ince) genç bir kadın.","e2":"They won by a slender majority.","e2t":"Az farkla (kısıtlı bir çoğunlukla) kazandılar."},{"w":"slice","tr":"dilim / dilimlemek / parça","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat piece of food cut from a larger piece","dt":"Büyük bir parçadan kesilmiş düz yiyecek parçası","e1":"A slice of bread.","e1t":"Bir dilim ekmek.","e2":"Slice the onions thinly.","e2t":"Soğanları ince ince dilimleyin."},{"w":"slick","tr":"kaygan / usta işi / kurnaz / yağ tabakası","te":"Adjective/Noun/Verb","tt":"Operating in a smooth way; or slippery; or a layer of oil","de":"Pürüzsüz işleyen; veya kaygan; veya yağ tabakası","dt":"A slick advertising campaign.","e1":"Usta işi (profesyonel) bir reklam kampanyası.","e1t":"Oil slick.","e2":"Denizdeki petrol tabakası.","e2t":""},{"w":"slight","tr":"hafif / az / küçük / küçümsemek","te":"Adjective/Noun/Verb","tt":"Small in amount or degree; or to insult someone","de":"Miktar veya derece olarak küçük; veya birini küçümsemek","dt":"A slight headache.","e1":"Hafif bir baş ağrısı.","e1t":"I don't have the slightest idea.","e2":"En ufak bir fikrim yok.","e2t":""},{"w":"slim","tr":"zayıf / ince / az / zayıflamak","te":"Adjective/Verb","tt":"Thin in an attractive way; or very small (chance)","de":"Çekici bir şekilde zayıf; veya çok az (şans)","dt":"She has a slim figure.","e1":"İnce bir fiziği var.","e1t":"A slim chance of success.","e2":"Zayıf bir başarı şansı.","e2t":""},{"w":"sling","tr":"asmak / fırlatmak / askı (kol)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device for supporting a broken arm; or to throw","dt":"Kırık kolu desteklemek için kullanılan araç; veya fırlatmak","e1":"His arm was in a sling.","e1t":"Kolu askıdaydı.","e2":"To sling a bag over your shoulder.","e2t":"Çantayı omuzuna asmak (atmak)."},{"w":"slip","tr":"kaymak / hata / kâğıt parçası / sıyrılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To slide without meaning to; or a small mistake","dt":"İstemeden kaymak; veya küçük hata","e1":"Be careful not to slip on the ice.","e1t":"Buzda kaymamaya dikkat et.","e2":"A slip of the tongue.","e2t":"Dil sürçmesi."},{"w":"slogan","tr":"slogan / düstur","te":"Noun","tt":"İsim","de":"A short easily remembered phrase used in advertising","dt":"Reklamcılıkta kullanılan, kolay hatırlanan kısa ifade","e1":"A famous advertising slogan.","e1t":"Ünlü bir reklam sloganı.","e2":"Political slogans.","e2t":"Siyasi sloganlar."},{"w":"slope","tr":"eğim / yamaç / eğimli olmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A surface that is higher at one end than the other","dt":"Bir ucu diğerinden daha yüksek olan yüzey","e1":"A steep slope.","e1t":"Dik bir yamaç (eğim).","e2":"Ski slope.","e2t":"Kayak pisti."},{"w":"slot","tr":"yuva / delik / zaman dilimi / yerleştirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long narrow hole for putting something in","dt":"Bir şeyi koymak için uzun dar delik","e1":"To put a coin in the slot.","e1t":"Deliğe bozuk para atmak.","e2":"A time slot (in a schedule).","e2t":"(Programdaki) zaman dilimi."},{"w":"slum","tr":"gecekondu mahallesi / varoş","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very poor and crowded area of a city","dt":"Şehrin çok fakir ve kalabalık bölgesi","e1":"To live in a slum.","e1t":"Gecekondu mahallesinde yaşamak.","e2":"Slum clearance.","e2t":"Gecekondu dönüşümü (temizlenmesi)."},{"w":"slumber","tr":"uyumak / uyku","te":"Verb/Noun","tt":"Fiil/İsim","de":"To sleep (literary)","dt":"Uyumak (edebi)","e1":"The city slumbers.","e1t":"Şehir uyuyor.","e2":"To fall into a deep slumber.","e2t":"Derin bir uykuya dalmak."},{"w":"slump","tr":"ani düşüş / çökmek / durgunluk","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fall or decrease suddenly and by a large amount","dt":"Aniden ve büyük miktarda düşmek veya azalmak","e1":"Sales slumped by 20%.","e1t":"Satışlar %20 oranında düştü (çöktü).","e2":"An economic slump.","e2t":"Ekonomik durgunluk (çöküş)."},{"w":"sly","tr":"kurnaz / sinsi / gizli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Deceiving people in a clever way; or secret","dt":"İnsanları zekice aldatan; veya gizli","e1":"A sly smile.","e1t":"Kurnazca bir gülümseme.","e2":"On the sly (secretly).","e2t":"Gizlice (kaşla göz arasında)."},{"w":"smash","tr":"paramparça etmek / çarpmak / büyük başarı","te":"Verb/Noun/Adj","tt":"To break into many pieces; or a great success","de":"Birçok parçaya ayırmak; veya büyük başarı","dt":"He smashed the window with a brick.","e1":"Pencereyi bir tuğlayla paramparça etti.","e1t":"The song was a smash hit.","e2":"Şarkı büyük bir hit (başarı) oldu.","e2t":""},{"w":"smog","tr":"dumanlı sis / hava kirliliği","te":"Noun","tt":"İsim","de":"A mixture of smoke, gases, and chemicals","dt":"Duman, gaz ve kimyasalların karışımı","e1":"The city was covered in smog.","e1t":"Şehir hava kirliliği (dumanlı sis) ile kaplıydı.","e2":"Smog alerts.","e2t":"Hava kirliliği uyarıları."},{"w":"smuggle","tr":"kaçakçılığını yapmak / gizlice sokmak","te":"Verb","tt":"Fiil","de":"To take things into or out of a country illegally","dt":"Bir ülkeye yasadışı yollarla mal sokmak veya çıkarmak","e1":"To smuggle drugs.","e1t":"Uyuşturucu kaçakçılığı yapmak.","e2":"He managed to smuggle a letter out of prison.","e2t":"Hapishaneden dışarı gizlice bir mektup çıkarmayı başardı."},{"w":"snack","tr":"atıştırmalık / ara öğün / atıştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small amount of food eaten between meals","dt":"Öğün aralarında yenen az miktarda yemek","e1":"A quick snack.","e1t":"Hızlı bir atıştırmalık.","e2":"I usually snack on fruit.","e2t":"Genellikle meyve atıştırırım."},{"w":"snag","tr":"pürüz / gizli engel / takılmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small problem or difficulty; or to catch on something","dt":"Küçük bir sorun veya zorluk; veya bir yere takılmak","e1":"There's just one snag...","e1t":"Sadece bir pürüz var...","e2":"I snagged my sweater on a nail.","e2t":"Kazağımı bir çiviye taktım (yırttım)."},{"w":"snail","tr":"salyangoz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small soft creature with a hard round shell","dt":"Sert yuvarlak kabuğu olan küçük yumuşak canlı","e1":"Moving at a snail's pace (very slowly).","e1t":"Salyangoz hızıyla (çok yavaş) ilerlemek.","e2":"Snail mail (traditional post).","e2t":"Klasik posta (yavaş posta)."},{"w":"snap","tr":"şaklatmak / çıt diye kırılmak / anlık / terslemek","te":"Verb/Noun/Adj/Adv","tt":"To break suddenly with a sharp noise; or to do quickly","de":"Keskin bir sesle aniden kırılmak; veya hızlıca yapmak","dt":"The branch snapped under his weight.","e1":"Dal onun ağırlığı altında çıt diye kırıldı.","e1t":"A snap decision.","e2":"Anlık (acele) bir karar.","e2t":""},{"w":"snare","tr":"tuzak / kapana kıstırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A trap for catching animals; or a trick","dt":"Hayvan yakalamak için tuzak; veya hile","e1":"To set a snare.","e1t":"Tuzak kurmak.","e2":"Snare drum.","e2t":"Trampet."},{"w":"snarl","tr":"hırlamak / karışıklık / (trafik) tıkanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make an angry sound while showing teeth; or a mess","dt":"Diş göstererek öfkeli bir ses çıkarmak; veya karışıklık","e1":"The dog snarled at me.","e1t":"Köpek bana hırladı.","e2":"Traffic was snarled up for hours.","e2t":"Trafik saatlerce tıkandı (karıştı)."},{"w":"snatch","tr":"kapmak / kapıp kaçmak / ara / parça","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take something quickly and often rudely","dt":"Bir şeyi hızlıca ve genellikle kaba bir şekilde almak","e1":"A thief snatched her handbag.","e1t":"Bir hırsız el çantasını kapıp kaçtı.","e2":"Snatches of conversation.","e2t":"Konuşmadan bölümler (parçalar)."},{"w":"sneak","tr":"gizlice girmek / sinsi / ispiyoncu","te":"Verb/Noun/Adj","tt":"To go somewhere quietly so you are not seen","de":"Görünmeden sessizce bir yere gitmek","dt":"He sneaked out of the house.","e1":"Evden gizlice süzüldü.","e1t":"To have a sneak preview.","e2":"Gizlice (önceden) bir göz atmak.","e2t":""},{"w":"sneer","tr":"küçümseyerek gülmek / dudak bükmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To show lack of respect with a facial expression","dt":"Yüz ifadesiyle saygısızlık (küçümseme) göstermek","e1":"\"You'll never succeed,\" he sneered.","e1t":"\"Asla başaramayacaksın,\" diye dudak büktü (alay etti).","e2":"A cold sneer.","e2t":"Soğuk bir küçümseme."},{"w":"sneeze","tr":"hapşırmak / aksırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To suddenly blow air out through your nose","dt":"Burun yoluyla aniden hava fırlatmak","e1":"The dust made me sneeze.","e1t":"Toz beni hapşırttı.","e2":"Bless you! (after a sneeze).","e2t":"Çok yaşa!"},{"w":"sniff","tr":"koklamak / burnunu çekmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To breathe air in through your nose to smell or hear","dt":"Koklamak veya ses duymak için burnundan hava çekmek","e1":"The dog sniffed the ground.","e1t":"Köpek yerleri kokladı.","e2":"To sniff with a cold.","e2t":"Soğuk algınlığıyla burnunu çekmek."},{"w":"snore","tr":"horlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To breathe noisily while you are asleep","dt":"Uyurken gürültülü nefes almak","e1":"He was snoring loudly.","e1t":"Yüksek sesle horluyordu.","e2":"To cure snoring.","e2t":"Horlamayı tedavi etmek."},{"w":"snowstorm","tr":"kar fırtınası / tipi","te":"Noun","tt":"İsim","de":"A storm with a lot of snow and strong winds","dt":"Çok kar ve güçlü rüzgârların olduğu fırtına","e1":"We were stuck in a snowstorm.","e1t":"Kar fırtınasında mahsur kaldık.","e2":"Heavy snowstorm.","e2t":"Şiddetli kar fırtınası (tipi)."},{"w":"soak","tr":"sırılsıklam etmek / ıslatmak / emmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something very wet; or to stay in water","dt":"Bir şeyi çok ıslatmak; veya suyun içinde kalmak","e1":"The rain soaked us to the skin.","e1t":"Yağmur bizi iliğimize kadar ıslattı.","e2":"Soak the beans overnight.","e2t":"Fasulyeleri geceden suya koyun (ıslatın)."},{"w":"soar","tr":"hızla yükselmek / süzülmek / artmak","te":"Verb","tt":"Fiil","de":"To rise high into the air; or to increase quickly","dt":"Havada yükseklere çıkmak; veya hızla artmak","e1":"The eagle soared above the mountains.","e1t":"Kartal dağların üzerinde süzüldü.","e2":"Temperatures soared to 40 degrees.","e2t":"Sıcaklıklar 40 dereceye fırladı (yükseldi)."},{"w":"sob","tr":"hıçkıra hıçkıra ağlamak / hıçkırık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cry noisily while taking short breaths","dt":"Kısa nefesler alarak gürültülü ağlamak","e1":"She started to sob uncontrollably.","e1t":"Kontrolsüzce hıçkırarak ağlamaya başladı.","e2":"A muffled sob.","e2t":"Boğuk bir hıçkırık."},{"w":"sober","tr":"ayık / ciddi / ağırbaşlı / ayılmak","te":"Adjective/Verb","tt":"Not drunk; or serious and sensible","de":"Sarhoş olmayan; veya ciddi ve mantıklı","dt":"He is a very sober person.","e1":"O çok ağırbaşlı (ciddi) biridir.","e1t":"Are you sober enough to drive?","e2":"Araba sürecek kadar ayık mısın?","e2t":""},{"w":"sociology","tr":"sosyoloji / toplum bilim","te":"Noun","tt":"İsim","de":"The study of the relationships between people living in groups","dt":"Gruplar halinde yaşayan insanlar arasındaki ilişkilerin incelenmesi","e1":"She has a degree in sociology.","e1t":"Sosyoloji diploması var.","e2":"Rural sociology.","e2t":"Köy sosyolojisi."},{"w":"software","tr":"yazılım","te":"Noun","tt":"İsim","de":"Programs used by a computer","dt":"Bilgisayar tarafından kullanılan programlar","e1":"Educational software.","e1t":"Eğitici yazılım.","e2":"To install new software.","e2t":"Yeni yazılım yüklemek."},{"w":"solar","tr":"güneşle ilgili / güneşsel","te":"Adjective","tt":"Sıfat","de":"Relating to the sun","dt":"Güneş ile ilgili","e1":"Solar energy.","e1t":"Güneş enerjisi.","e2":"The solar system.","e2t":"Güneş sistemi."},{"w":"sole","tr":"tek / biricik / taban (ayakkabı/ayak) / dil balığı","te":"Adjective/Noun/Verb","tt":"Being the only one; or the bottom part of a foot","de":"Tek olan; veya ayak/ayakkabı tabanı","dt":"My sole purpose is to help.","e1":"Tek amacım yardım etmek.","e1t":"The soles of my shoes are worn out.","e2":"Ayakkabılarımın tabanları aşınmış.","e2t":""},{"w":"solemn","tr":"ciddi / ağırbaşlı / törensel","te":"Adjective","tt":"Sıfat","de":"Serious and without any humor","dt":"Ciddi ve espri barındırmayan","e1":"A solemn promise.","e1t":"Ciddi (resmi) bir vaat.","e2":"A solemn occasion.","e2t":"Törensel (resmi/ciddi) bir durum."},{"w":"solidarity","tr":"dayanışma","te":"Noun","tt":"İsim","de":"Agreement and support between members of a group","dt":"Bir grup üyesi arasındaki anlaşma ve destek","e1":"Social solidarity.","e1t":"Sosyal dayanışma.","e2":"To show solidarity with the strikers.","e2t":"Grevdekilerle dayanışma göstermek."},{"w":"solidify","tr":"katılaşmak / sertleşmek / somutlaşmak","te":"Verb","tt":"Fiil","de":"To become solid; or to make a plan more certain","dt":"Katı hale gelmek; veya bir planı daha kesin hale getirmek","e1":"The lava began to solidify.","e1t":"Lav katılaşmaya başladı.","e2":"This success solidified his position.","e2t":"Bu başarı onun konumunu sağlamlaştırdı (somutlaştırdı)."},{"w":"solitary","tr":"yalnız / tek başına / ıssız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Being the only one; or enjoying being alone","dt":"Tek olan; veya yalnız kalmayı seven","e1":"A solitary traveler.","e1t":"Yalnız bir gezgin.","e2":"Solitary confinement (in prison).","e2t":"Hücre hapsi (tecrit)."},{"w":"solo","tr":"solo / tek başına","te":"Adjective/Adverb/Noun/Verb","tt":"Done by one person alone","de":"Tek bir kişi tarafından yapılan","dt":"A solo flight.","e1":"Tek başına uçuş.","e1t":"He performed a guitar solo.","e2":"Gitar solosu sergiledi.","e2t":""},{"w":"soluble","tr":"çözünür / halledilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be dissolved in a liquid; or a problem that can be solved","dt":"Bir sıvıda çözünebilen; veya çözülebilir bir sorun","e1":"Soluble aspirin.","e1t":"Suda çözünen aspirin.","e2":"A soluble problem.","e2t":"Halledilebilir (çözümü olan) bir problem."},{"w":"solute","tr":"çözünen madde","te":"Noun","tt":"İsim","de":"A substance that is dissolved in a liquid","dt":"Bir sıvıda çözünen madde","e1":"Salt is the solute in a saltwater solution.","e1t":"Tuz, tuzlu su çözeltisindeki çözünen maddedir.","e2":"Concentration of the solute.","e2t":"Çözünen maddenin konsantrasyonu."},{"w":"solvent","tr":"çözücü / borcunu ödeyebilir","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A liquid that can dissolve other substances; or having enough money to pay debts","dt":"Diğer maddeleri çözebilen sıvı; veya borçlarını ödeyecek kadar parası olan","e1":"Water is a universal solvent.","e1t":"Su evrensel bir çözücüdür.","e2":"The company is barely solvent.","e2t":"Şirket ancak borçlarını ödeyebilecek durumda."},{"w":"soothe","tr":"yatıştırmak / dindirmek / sakinleştirmek","te":"Verb","tt":"Fiil","de":"To make someone feel calm or make a pain less severe","dt":"Birini sakinleştirmek veya bir acıyı azaltmak","e1":"To soothe a crying baby.","e1t":"Ağlayan bir bebeği yatıştırmak.","e2":"This cream will soothe the irritation.","e2t":"Bu krem tahrişi dindirecektir."},{"w":"sophisticated","tr":"gelişmiş / karmaşık / kültürlü / sofistike","te":"Adjective","tt":"Sıfat","de":"Developed to a high degree; or having a lot of experience of culture","dt":"İleri düzeyde gelişmiş; veya kültür birikimi olan","e1":"Sophisticated computer systems.","e1t":"Gelişmiş (karmaşık) bilgisayar sistemleri.","e2":"A sophisticated young woman.","e2t":"Kültürlü (sofistike) genç bir kadın."},{"w":"sophomore","tr":"(lise/üniversite) ikinci sınıf öğrencisi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A student in the second year of high school or college (US)","dt":"Lise veya üniversite ikinci sınıf öğrencisi","e1":"He is a sophomore at Harvard.","e1t":"Harvard'da ikinci sınıf öğrencisidir.","e2":"Sophomore year.","e2t":"İkinci sınıf yılı."},{"w":"sorrow","tr":"hüzün / keder / üzüntü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of great sadness","dt":"Büyük üzüntü hissi","e1":"To express sorrow.","e1t":"Üzüntülerini dile getirmek.","e2":"Joy and sorrow.","e2t":"Sevinç ve keder."},{"w":"soul","tr":"ruh / can / öz","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The spiritual part of a person; or the quality of being human","dt":"Bir insanın ruhani kısmı; veya insan olma niteliği","e1":"May his soul rest in peace.","e1t":"Ruhu şad olsun (huzur içinde uyusun).","e2":"He is the soul of the company.","e2t":"O şirketin ruhudur (özüdür)."},{"w":"soundproof","tr":"ses geçirmez / yalıtımlı","te":"Adjective/Verb","tt":"Not allowing sound to pass through","de":"Sesin geçmesine izin vermeyen","dt":"A soundproof room.","e1":"Ses geçirmez bir oda.","e1t":"To soundproof a studio.","e2":"Bir stüdyoyu ses yalıtımlı hale getirmek.","e2t":""},{"w":"soup","tr":"çorba","te":"Noun/Verb","tt":"İsim/Fiil","de":"A liquid food made from meat or vegetables","dt":"Et veya sebzeden yapılan sıvı yiyecek","e1":"Lentil soup.","e1t":"Mercimek çorbası.","e2":"To eat soup.","e2t":"Çorba içmek (yemek)."},{"w":"sour","tr":"ekşi / somurtkan / bozulmuş","te":"Adjective/Noun/Verb","tt":"Having a sharp taste like lemon; or unfriendly","de":"Limon gibi keskin bir tadı olan; veya kaba/asık suratlı","dt":"Sour milk.","e1":"Bozulmuş (ekşimiş) süt.","e1t":"A sour look.","e2":"Somurtkan (aksi) bir bakış.","e2t":""},{"w":"source","tr":"kaynak / köken / kaynakça","te":"Noun/Verb","tt":"İsim/Fiil","de":"Where something comes from; or a document used for information","dt":"Bir şeyin geldiği yer; veya bilgi için kullanılan belge","e1":"A source of energy.","e1t":"Enerji kaynağı.","e2":"Reliable source of information.","e2t":"Güvenilir bilgi kaynağı."},{"w":"souvenir","tr":"hediyelik eşya / hatıra","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something you buy or keep to help you remember a place","dt":"Bir yeri hatırlamanıza yardımcı olması için aldığınız şey","e1":"I bought a small souvenir from Paris.","e1t":"Paris'ten küçük bir hediyelik eşya aldım.","e2":"Souvenir shop.","e2t":"Hediyelik eşya dükkanı."},{"w":"sovereign","tr":"egemen / bağımsız / hükümdar","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having total power; or a king/queen","dt":"Tam güce sahip olan; veya kral/kraliçe","e1":"A sovereign state.","e1t":"Egemen (bağımsız) bir devlet.","e2":"The sovereign of the nation.","e2t":"Ulusun hükümdarı."},{"w":"sovereignty","tr":"egemenlik / bağımsızlık","te":"Noun","tt":"İsim","de":"The power of a country to control its own government","dt":"Bir ülkenin kendi hükümetini kontrol etme gücü","e1":"National sovereignty.","e1t":"Milli egemenlik.","e2":"To respect the sovereignty of other nations.","e2t":"Diğer ulusların egemenliğine saygı duymak."},{"w":"sow","tr":"ekmek (tohum) / yaymak / dişi domuz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To plant seeds in the ground; or a female pig","dt":"Toprağa tohum ekmek; veya dişi domuz","e1":"To sow seeds of doubt.","e1t":"Şüphe tohumları ekmek (yaymak).","e2":"You reap what you sow.","e2t":"Ne ekersen onu biçersin."},{"w":"space","tr":"alan / uzay / boşluk / yerleştirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An empty area; or the area outside the Earth's atmosphere","dt":"Boş alan; veya Dünya atmosferinin dışındaki alan","e1":"Outer space.","e1t":"Uzay.","e2":"Parking space.","e2t":"Park yeri."},{"w":"spacious","tr":"ferah / geniş / havadar","te":"Adjective","tt":"Sıfat","de":"Having a lot of space inside","dt":"İçinde çok fazla alan (boşluk) olan","e1":"A spacious living room.","e1t":"Ferah (geniş) bir oturma odası.","e2":"Spacious office.","e2t":"Geniş ofis."},{"w":"spade","tr":"kürek (sivri uçlu/bel) / maça (iskambil)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for digging; or a suit in cards","dt":"Kazma aleti (bel küreği); veya kağıt oyununda maça","e1":"To use a spade in the garden.","e1t":"Bahçede bel küreği kullanmak.","e2":"Ace of spades.","e2t":"Maça ası."},{"w":"span","tr":"süre / mesafe / kanat açıklığı / kapsamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The length of time or distance between two points","dt":"İki nokta arasındaki zaman veya mesafe","e1":"Life span.","e1t":"Yaşam süresi.","e2":"A bridge with a wide span.","e2t":"Geniş açıklığı olan bir köprü."},{"w":"spank","tr":"şaplak atmak / kıçına vurmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit someone, especially a child, with your open hand","dt":"Birine, özellikle bir çocuğa, açık elinle vurmak","e1":"His father spanked him for being naughty.","e1t":"Babası yaramazlık yaptığı için ona şaplak attı.","e2":"To give someone a spanking.","e2t":"Birini dövmek (şaplaklamak)."},{"w":"spark","tr":"kıvılcım / ateşlemek / başlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small bright flash of light; or to start something","dt":"Küçük parlak ışık parlaması; veya bir şeyi başlatmak","e1":"A spark from the fire.","e1t":"Ateşten sıçrayan bir kıvılcım.","e2":"The protest sparked a revolution.","e2t":"Protesto bir devrimi ateşledi (başlattı)."},{"w":"sparkle","tr":"ışıldamak / parlamak / pırıltı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shine brightly with small flashes of light","dt":"Küçük ışık parlamalarıyla ışıldamak","e1":"The diamonds sparkled in the light.","e1t":"Elmaslar ışıkta parladı.","e2":"Sparkling water (soda).","e2t":"Maden suyu (gazlı su)."},{"w":"sparse","tr":"seyrek / az / kıt","te":"Adjective","tt":"Sıfat","de":"Small in number and spread over a large area","dt":"Sayıca az ve geniş bir alana yayılmış","e1":"Sparse population.","e1t":"Seyrek nüfus.","e2":"Sparse vegetation.","e2t":"Seyrek bitki örtüsü."},{"w":"spasm","tr":"spazm / kasılma / ani nöbet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden muscle movement that you cannot control","dt":"Kontrol edilemeyen ani kas hareketi","e1":"Muscle spasm.","e1t":"Kas spazmı.","e2":"A spasm of pain.","e2t":"Ani bir ağrı nöbeti (kasılması)."},{"w":"spatial","tr":"mekansal / uzaysal","te":"Adjective","tt":"Sıfat","de":"Relating to space or position","dt":"Uzay veya konum ile ilgili","e1":"Spatial awareness.","e1t":"Mekansal farkındalık (konum algısı).","e2":"Spatial distribution.","e2t":"Mekansal dağılım."},{"w":"spawn","tr":"(balık vb.) yumurtlamak / neden olmak / döl","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce eggs (for fish); or to cause something to start","dt":"(Balık için) yumurta bırakmak; veya bir şeyin başlamasına neden olmak","e1":"The fish swim upstream to spawn.","e1t":"Balıklar yumurtlamak için nehrin yukarısına yüzerler.","e2":"The success spawned many imitations.","e2t":"Bu başarı birçok taklidin doğmasına neden oldu."},{"w":"spear","tr":"mızrak / zıpkın / mızrakla vurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long pole with a sharp point used as a weapon","dt":"Silah olarak kullanılan keskin uçlu uzun sopa","e1":"He caught a fish with a spear.","e1t":"Mızrakla (zıpkınla) bir balık yakaladı.","e2":"To spear a piece of meat.","e2t":"Bir parça ete çatal (mızrak) saplamak."},{"w":"specialize / specialise","tr":"uzmanlaşmak / branşlaşmak","te":"Verb","tt":"Fiil","de":"To spend most of your time on a particular subject","dt":"Zamanınızın çoğunu belirli bir konuya ayırmak","e1":"He specializes in international law.","e1t":"Uluslararası hukuk alanında uzmanlaşıyor.","e2":"Specialized knowledge.","e2t":"Uzmanlık bilgisi."},{"w":"species","tr":"tür / cins","te":"Noun","tt":"İsim","de":"A group of animals or plants that are similar","dt":"Benzer hayvan veya bitki grubu","e1":"Endangered species.","e1t":"Nesli tükenmekte olan türler.","e2":"The human species.","e2t":"İnsan türü."},{"w":"specific","tr":"belirli / özel / özgü","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to one particular thing","dt":"Belirli bir şeye ilişkin","e1":"For no specific reason.","e1t":"Belirli bir sebep olmaksızın.","e2":"Specific needs.","e2t":"Özel ihtiyaçlar."},{"w":"specification","tr":"şartname / teknik özellik / ayrıntı","te":"Noun","tt":"İsim","de":"A detailed description of how something should be made","dt":"Bir şeyin nasıl yapılması gerektiğine dair detaylı açıklama","e1":"To meet the technical specifications.","e1t":"Teknik özelliklere uymak.","e2":"Job specification.","e2t":"İş tanımı (şartnamesi)."},{"w":"specify","tr":"belirtmek / açıkça söylemek","te":"Verb","tt":"Fiil","de":"To state something clearly and exactly","dt":"Bir şeyi net ve tam olarak belirtmek","e1":"Please specify your requirements.","e1t":"Lütfen gereksinimlerinizi belirtin.","e2":"The contract specifies that...","e2t":"Sözleşme ... olmasını şart koşuyor (belirtiyor)."},{"w":"specimen","tr":"örnek / numune / tip","te":"Noun","tt":"İsim","de":"A typical example; or a small amount of blood for testing","dt":"Tipik bir örnek; veya test için az miktarda kan/idrar","e1":"A blood specimen.","e1t":"Kan numunesi.","e2":"A fine specimen of an oak tree.","e2t":"Bir meşe ağacının güzel bir örneği."},{"w":"spectacle","tr":"gösteri / manzara / rüsvaylık","te":"Noun","tt":"İsim","de":"An unusual or exciting public show or event","dt":"Olağandışı veya heyecan verici halka açık gösteri veya olay","e1":"The opening ceremony was a magnificent spectacle.","e1t":"Açılış töreni muhteşem bir gösteriydi.","e2":"To make a spectacle of oneself.","e2t":"Kendini rüsvay etmek (herkesin içinde küçük düşmek)."},{"w":"spectacular","tr":"görkemli / muhteşem / olağanüstü","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Very exciting to look at; or very good","dt":"Bakması heyecan verici; veya çok iyi","e1":"A spectacular view of the mountains.","e1t":"Dağların muhteşem bir manzarası.","e2":"Spectacular success.","e2t":"Görkemli (olağanüstü) başarı."},{"w":"spectator","tr":"izleyici / seyirci","te":"Noun","tt":"İsim","de":"A person who watches an activity, especially a sports event","dt":"Bir etkinliği, özellikle spor etkinliğini izleyen kişi","e1":"The stadium was full of shouting spectators.","e1t":"Stadyum bağıran seyircilerle doluydu.","e2":"Spectator sports.","e2t":"Seyirci sporları."},{"w":"spectrum","tr":"spektrum / yelpaze / tayf","te":"Noun","tt":"İsim","de":"A range of different positions or opinions","dt":"Farklı görüşlerin veya konumların yelpazesi","e1":"A wide spectrum of political views.","e1t":"Geniş bir siyasi görüş yelpazesi.","e2":"The visible spectrum of light.","e2t":"Işığın görünür tayfı (spektrumu)."},{"w":"speculate","tr":"tahminde bulunmak / kurgulamak / spekülasyon yapmak","te":"Verb","tt":"Fiil","de":"To guess about something without having all the facts","dt":"Tüm gerçeklere sahip olmadan bir şey hakkında tahminde bulunmak","e1":"I don't want to speculate about the causes of the crash.","e1t":"Kazanın nedenleri hakkında tahminde bulunmak (spekülasyon yapmak) istemiyorum.","e2":"To speculate on the stock market.","e2t":"Borsada spekülasyon yapmak."},{"w":"speedometer","tr":"hız göstergesi","te":"Noun","tt":"İsim","de":"A device in a vehicle that shows how fast it is going","dt":"Araçta ne kadar hızlı gidildiğini gösteren cihaz","e1":"The speedometer showed 100 km/h.","e1t":"Hız göstergesi 100 km/s gösteriyordu.","e2":"To check the speedometer.","e2t":"Hız göstergesini kontrol etmek."},{"w":"sphere","tr":"küre / alan / saha","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shape like a ball; or a particular area of activity","dt":"Top gibi bir şekil; veya belirli bir faaliyet alanı","e1":"The Earth is not a perfect sphere.","e1t":"Dünya mükemmel bir küre değildir.","e2":"Within the political sphere.","e2t":"Siyasi alan içinde."},{"w":"spill","tr":"dökmek / sızdırmak / dökülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To flow over the edge of a container by accident","dt":"Bir kabın kenarından kazara dışarı akmak","e1":"I accidentally spilled my coffee on the rug.","e1t":"Yanlışlıkla kahvemi kilimin üzerine döktüm.","e2":"To spill the beans (to tell a secret).","e2t":"Baklayı ağzından çıkarmak (sırrı ifşa etmek)."},{"w":"spin","tr":"dönmek / döndürmek / örmek (ağ) / çarpıtma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn around and around quickly; or to tell a story","dt":"Kendi etrafında hızla dönmek; veya hikaye anlatmak","e1":"The Earth spins on its axis.","e1t":"Dünya kendi ekseni etrafında döner.","e2":"The spider is spinning a web.","e2t":"Örümcek ağ örüyor."},{"w":"spine","tr":"omurga / bel kemiği / (kitap) sırtı","te":"Noun","tt":"İsim","de":"The line of bones down the middle of the back","dt":"Sırtın ortasındaki kemik hattı","e1":"He injured his spine in a fall.","e1t":"Düşerek omurgasını zedeledi.","e2":"The title is printed on the spine of the book.","e2t":"Başlık kitabın sırtına basılmış."},{"w":"spiral","tr":"sarmal / spiral / sarmal biçimde gitmek","te":"Noun/Adj/Verb","tt":"A shape that curls around a central point","de":"Merkezi bir nokta etrafında dolanan şekil","dt":"A spiral staircase.","e1":"Döner (spiral) merdiven.","e1t":"Inflation is in an upward spiral.","e2":"Enflasyon yukarı doğru bir sarmal içinde.","e2t":""},{"w":"spiritual","tr":"ruhsal / manevi / dini","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to deep feelings and beliefs, especially religious","dt":"Derin duygu ve inançlarla, özellikle dini olanlarla ilgili","e1":"I’m not religious, but I’m a spiritual person.","e1t":"Dindar değilim ama manevi (ruhsal) biriyim.","e2":"Spiritual needs.","e2t":"Manevi ihtiyaçlar."},{"w":"spit","tr":"tükürmek / şiş (kebap) / kumsal dili","te":"Verb/Noun","tt":"Fiil/İsim","de":"To force liquid out of your mouth","dt":"Ağızdan dışarı sıvı fırlatmak","e1":"It is rude to spit in public.","e1t":"Toplum içinde tükürmek kabadır.","e2":"Meat on a spit.","e2t":"Şişte et."},{"w":"spite","tr":"nispet / inat / kin /","te":"e rağmen","tt":"Noun/Verb","de":"İsim/Fiil","dt":"A feeling of wanting to hurt or upset someone","e1":"Birine zarar verme veya onu üzme isteği","e1t":"He did it just to spite me.","e2":"Bunu sırf bana nispet yapmak (beni kızdırmak) için yaptı.","e2t":"In spite of (despite)."},{"w":"splash","tr":"sıçramak / sıçratmak / su sesi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit a liquid so that it moves in many directions","dt":"Bir sıvıya vurarak her yöne dağılmasını sağlamak","e1":"The kids were splashing in the pool.","e1t":"Çocuklar havuzda su sıçratıyordu.","e2":"To make a splash (to get a lot of attention).","e2t":"Ses getirmek (büyük ilgi çekmek)."},{"w":"splendid","tr":"görkemli / muhteşem / harika","te":"Adjective","tt":"Sıfat","de":"Very impressive, beautiful, or excellent","dt":"Çok etkileyici, güzel veya mükemmel","e1":"We had a splendid holiday.","e1t":"Harika bir tatil geçirdik.","e2":"A splendid idea!","e2t":"Muhteşem bir fikir!"},{"w":"splendor / splendour","tr":"görkem / ihtişam / şatafat","te":"Noun","tt":"İsim","de":"Great beauty or impressive appearance","dt":"Büyük güzellik veya etkileyici görünüm","e1":"The splendor of the Ottoman palaces.","e1t":"Osmanlı saraylarının ihtişamı.","e2":"In all its splendor.","e2t":"Tüm görkemiyle."},{"w":"split","tr":"bölmek / yarılmak / ayrılmak / yarık","te":"Verb/Noun/Adj","tt":"To divide into two or more parts","de":"İki veya daha fazla parçaya bölmek","dt":"To split the bill.","e1":"Hesabı bölüşmek.","e1t":"The party split into two factions.","e2":"Parti iki gruba (hizbe) bölündü.","e2t":""},{"w":"spoil","tr":"bozmak / şımartmak / ganimet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To destroy the value or quality of something; or to be too kind to a child","dt":"Bir şeyin değerini/kalitesini bozmak; veya bir çocuğu çok şımartmak","e1":"Don't spoil your appetite before dinner.","e1t":"Yemekten önce iştahını bozma.","e2":"They spoil their children with expensive gifts.","e2t":"Çocuklarını pahalı hediyelerle şımartıyorlar."},{"w":"spokesman / spokeswoman","tr":"sözcü","te":"Noun","tt":"İsim","de":"A person who chosen to speak for a group","dt":"Bir grup adına konuşmak için seçilen kişi","e1":"A government spokesman.","e1t":"Hükümet sözcüsü.","e2":"To act as a spokesman.","e2t":"Sözcü olarak hareket etmek."},{"w":"sponge","tr":"sünger / asalaklık etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A soft substance full of holes used for washing","dt":"Yıkama için kullanılan delikli yumuşak madde","e1":"Natural sponge.","e1t":"Doğal sünger.","e2":"To sponge off someone (to live at their expense).","e2t":"Birinin sırtından geçinmek (asalaklık etmek)."},{"w":"sponsor","tr":"sponsor / destekleyici / kefil / desteklemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person or company that pays for a show or athlete","dt":"Bir gösteri veya sporcu için ödeme yapan kişi veya şirket","e1":"The event was organized by its main sponsor.","e1t":"Etkinlik ana sponsoru tarafından organize edildi.","e2":"To sponsor a child's education.","e2t":"Bir çocuğun eğitimine sponsor olmak (desteklemek)."},{"w":"spontaneous","tr":"kendiliğinden olan / doğal / anlık","te":"Adjective","tt":"Sıfat","de":"Happening naturally or without being planned","dt":"Doğal olarak veya planlanmadan gerçekleşen","e1":"A spontaneous reaction.","e1t":"Anlık (doğal) bir tepki.","e2":"Spontaneous applause.","e2t":"Kendiliğinden yükselen alkış."},{"w":"spot","tr":"nokta / yer / leke / fark etmek","te":"Noun/Verb/Adj","tt":"A small round mark; or a particular place; or to notice","de":"Küçük yuvarlak işaret; veya belirli bir yer; veya fark etmek","dt":"A blind spot.","e1":"Kör nokta.","e1t":"On the spot (immediately).","e2":"Derhal (orada/o anda).","e2t":""},{"w":"spotlight","tr":"projektör / ilgi odağı / vurgulamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A powerful light used in a theater; or public attention","dt":"Tiyatroda kullanılan güçlü ışık; veya kamuoyunun ilgisi","e1":"To be in the spotlight.","e1t":"İlgi odağı olmak.","e2":"The report spotlights the problem of poverty.","e2t":"Rapor yoksulluk sorununa ışık tutuyor (vurguluyor)."},{"w":"sprain","tr":"burkmak / burkulma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To injure a joint by twisting it suddenly","dt":"Bir eklemi aniden bükerek sakatlamak","e1":"I sprained my ankle playing football.","e1t":"Futbol oynarken ayak bileğimi burktum.","e2":"A painful sprain.","e2t":"Ağrılı bir burkulma."},{"w":"sprawl","tr":"yayılmak / sermek / (şehir) plansız büyümek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To spread your arms and legs out; or (of a city) to spread out","dt":"Kolları ve bacakları yayarak yatmak; veya (şehir için) yayılmak","e1":"He was sprawling on the sofa.","e1t":"Kanepede yayılmış yatıyordu.","e2":"Urban sprawl.","e2t":"Şehirleşmenin plansız yayılması."},{"w":"spray","tr":"püskürtmek / sprey / serpinti","te":"Noun/Verb","tt":"İsim/Fiil","de":"A mass of very small drops of liquid","dt":"Çok küçük sıvı damlacıkları kütlesi","e1":"Hair spray.","e1t":"Saç spreyi.","e2":"To spray the garden with insecticide.","e2t":"Bahçeye böcek ilacı püskürtmek."},{"w":"spread","tr":"yaymak / yayılmak / sürmek (ekmeğe) / çeşitlilik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cover a surface with a thin layer; or to increase","dt":"Bir yüzeyi ince bir tabaka ile kaplamak; veya artmak","e1":"To spread butter on bread.","e1t":"Ekmeğe tereyağı sürmek.","e2":"The news spread quickly.","e2t":"Haberler hızla yayıldı."},{"w":"spring","tr":"bahar / yay / kaynak / sıçramak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The season between winter and summer; or a coiled piece of metal","dt":"Kış ve yaz arasındaki mevsim; veya sarmal metal parça","e1":"Spring water.","e1t":"Kaynak suyu.","e2":"Bed springs.","e2t":"Yatak yayları."},{"w":"sprinkle","tr":"serpmek / sulamak / çiselemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To drop small pieces or drops of something over a surface","dt":"Bir yüzeye bir şeyin küçük parçalarını veya damlalarını dökmek","e1":"Sprinkle some salt over the meat.","e1t":"Etin üzerine biraz tuz serpin.","e2":"It's just sprinkling (light rain).","e2t":"Sadece çiseliyor."},{"w":"sprint","tr":"kısa mesafe koşusu / tam hız koşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short race at a very fast speed","dt":"Çok hızlı kısa mesafe yarışı","e1":"He won the 100","e1t":"meter sprint.","e2":"100 metre kısa mesafe koşusunu kazandı.","e2t":"To sprint to the finish line."},{"w":"sprout","tr":"filizlenmek / yeşermek / filiz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To begin to grow; or a part of a plant","dt":"Büyümeye başlamak; veya bitki parçası","e1":"The seeds are starting to sprout.","e1t":"Tohumlar filizlenmeye başlıyor.","e2":"Brussels sprouts.","e2t":"Brüksel lahanası."},{"w":"spur","tr":"teşvik etmek / mahmuz / dürtü","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that encourages you; or a sharp point on a boot","dt":"Sizi teşvik eden şey; veya bottaki keskin uç","e1":"The win was a spur to further success.","e1t":"Galibiyet, daha fazla başarı için bir teşvik oldu.","e2":"On the spur of the moment (suddenly).","e2t":"Bir anlık kararla (aniden)."},{"w":"squad","tr":"ekip / tim / manga","te":"Noun","tt":"İsim","de":"A small group of people working together","dt":"Birlikte çalışan küçük insan grubu","e1":"Police squad.","e1t":"Polis ekibi.","e2":"Death squad.","e2t":"Ölüm mangası."},{"w":"squander","tr":"savurmak / israf etmek / çarçur etmek","te":"Verb","tt":"Fiil","de":"To waste money, time, or an opportunity","dt":"Para, zaman veya fırsatı boşa harcamak","e1":"He squandered his fortune on gambling.","e1t":"Servetini kumarda savurdu (çarçur etti).","e2":"To squander an opportunity.","e2t":"Bir fırsatı boşa harcamak."},{"w":"square","tr":"kare / meydan / dürüst / karesini almak","te":"Noun/Adj/Verb/Adv","tt":"A shape with four equal sides; or an open area in a town","de":"Dört eşit kenarı olan şekil; veya kasabadaki açık alan","dt":"Times Square.","e1":"Times Meydanı.","e1t":"A square meal.","e2":"Doyurucu (sağlam) bir yemek.","e2t":""},{"w":"squash","tr":"ezmek / sıkıştırmak / kabak / skuaş (spor)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To crush something so that it becomes flat; or a type of vegetable","dt":"Bir şeyi düzleşecek şekilde ezmek; veya bir sebze türü","e1":"To squash a bug.","e1t":"Bir böceği ezmek.","e2":"We were squashed together on the bus.","e2t":"Otobüste birbirimize sıkışmıştık."},{"w":"squeak","tr":"gıcırdamak / ciyaklamak / ucu ucuna başarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a short, very high sound","dt":"Kısa ve çok tiz bir ses çıkarmak","e1":"The door squeaks.","e1t":"Kapı gıcırdıyor.","e2":"A mouse squeaks.","e2t":"Fare ciyaklar."},{"w":"squeeze","tr":"sıkmak / sıkıştırmak / suyunu çıkarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To press something firmly; or to get liquid out","dt":"Bir şeyi sıkıca bastırmak; veya suyunu çıkarmak","e1":"To squeeze a lemon.","e1t":"Limon sıkmak.","e2":"To squeeze someone's hand.","e2t":"Birinin elini sıkmak."},{"w":"squint","tr":"gözlerini kısmak / şaşılık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To look with eyes partly closed","dt":"Gözleri yarı kapalı bakmak","e1":"To squint in the bright sunlight.","e1t":"Parlak güneş ışığında gözlerini kısmak.","e2":"He has a slight squint.","e2t":"Hafif bir şaşılığı var."},{"w":"stab","tr":"bıçaklamak / saplamak / hamle","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push a sharp object into someone","dt":"Birine keskin bir nesne saplamak","e1":"He was stabbed in the chest.","e1t":"Göğsünden bıçaklandı.","e2":"A stab in the back (betrayal).","e2t":"Arkadan bıçaklama (ihanet)."},{"w":"stability","tr":"istikrar / denge / kararlılık","te":"Noun","tt":"İsim","de":"The state of being certain and not changing","dt":"Kesin olma ve değişmeme durumu","e1":"Economic stability.","e1t":"Ekonomik istikrar.","e2":"Emotional stability.","e2t":"Duygusal denge."},{"w":"stabilize / stabilise","tr":"stabilize etmek / dengelemek / saptamak","te":"Verb","tt":"Fiil","de":"To cause something to become fixed and stop changing","dt":"Bir şeyin sabitlenmesini ve değişmemesini sağlamak","e1":"To stabilize prices.","e1t":"Fiyatları dengelemek.","e2":"The patient's condition has stabilized.","e2t":"Hastanın durumu stabilize oldu (sabitlendi)."},{"w":"stable","tr":"ahır / istikrarlı / sağlam / dayanıklı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A building for horses; or fixed and steady","dt":"Atlar için bina; veya sabit ve dengeli","e1":"To keep horses in a stable.","e1t":"Atları ahırda tutmak.","e2":"A stable relationship.","e2t":"İstikrarlı bir ilişki."},{"w":"stack","tr":"yığın / deste / istiflemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A pile of things arranged one on top of another","dt":"Üst üste dizilmiş şeyler yığını","e1":"A stack of books.","e1t":"Bir kitap yığını (destesi).","e2":"To stack the chairs.","e2t":"Sandalyeleri istiflemek."},{"w":"stadium","tr":"stadyum / stad","te":"Noun","tt":"İsim","de":"A large structure for sports events","dt":"Spor etkinlikleri için büyük yapı","e1":"A football stadium.","e1t":"Futbol stadyumu.","e2":"To pack the stadium.","e2t":"Stadyumu doldurmak."},{"w":"staff","tr":"personel / kadro / değnek / asa","te":"Noun/Verb","tt":"İsim/Fiil","de":"All the people who work for an organization","dt":"Bir kuruluş için çalışan tüm insanlar","e1":"Teaching staff.","e1t":"Öğretmen kadrosu.","e2":"The hotel is fully staffed.","e2t":"Otel tam kadro (personel) çalışıyor."},{"w":"stagger","tr":"sendelemek / şaşırtmak / kademelendirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk unsteadily; or to shock someone greatly","dt":"Sarsılarak yürümek; veya birini çok şaşırtmak","e1":"He staggered home drunk.","e1t":"Sarhoş halde sendeleyerek eve gitti.","e2":"I was staggered by the news.","e2t":"Haberler karşısında şoke oldum (sarsıldım)."},{"w":"stagnant","tr":"durgun / ölü (su) / gelişmeyen","te":"Adjective","tt":"Sıfat","de":"(Of water/air) not flowing; or not developing","dt":"(Su/hava için) akmayan; veya gelişmeyen","e1":"Stagnant water.","e1t":"Durgun (pis) su.","e2":"A stagnant economy.","e2t":"Durgun (gelişmeyen) ekonomi."},{"w":"stain","tr":"leke / lekelemek / boyamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A dirty mark that is difficult to remove","dt":"Çıkarılması zor kirli iz","e1":"A coffee stain on the shirt.","e1t":"Gömlekte bir kahve lekesi.","e2":"To stain wood.","e2t":"Ahşabı boyamak (cilalamak)."},{"w":"staircase","tr":"merdiven / merdiven boşluğu","te":"Noun","tt":"İsim","de":"A set of stairs and the structure around them","dt":"Bir dizi basamak ve etrafındaki yapı","e1":"A winding staircase.","e1t":"Döner merdiven.","e2":"To walk up the staircase.","e2t":"Merdivenlerden çıkmak."},{"w":"stake","tr":"kazık / risk / hisse / bahis","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong wooden post; or money risked on a result","dt":"Güçlü ahşap direk; veya bir sonuç üzerine riske atılan para","e1":"To drive a stake into the ground.","e1t":"Yere bir kazık çakmak.","e2":"To have a stake in a company.","e2t":"Bir şirkette hissesi (çıkarı) olmak."},{"w":"stale","tr":"bayat / eskimiş / tatsız","te":"Adjective/Verb","tt":"(Of food) no longer fresh; or boring","de":"(Yiyecek için) artık taze olmayan; veya sıkıcı","dt":"Stale bread.","e1":"Bayat ekmek.","e1t":"Stale jokes.","e2":"Bayat (eskimiş) espriler.","e2t":""},{"w":"stalk","tr":"sap / sapıkça izlemek / sinsi sinsi yaklaşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The main stem of a plant; or to follow someone secretly","dt":"Bitkinin ana gövdesi; veya birini gizlice takip etmek","e1":"A celery stalk.","e1t":"Kereviz sapı.","e2":"To stalk a celebrity.","e2t":"Bir ünlüyü sapıkça takip etmek (izlemek)."},{"w":"stall","tr":"tezgah / kabin / oyalamak / (motor) durmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large table used for selling things; or to stop moving","dt":"Mal satmak için kullanılan büyük masa; veya durmak","e1":"A market stall.","e1t":"Pazar tezgahı.","e2":"Shower stall.","e2t":"Duş kabini."},{"w":"stammer","tr":"kekelemek / takılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak with difficulty, repeating sounds","dt":"Sesleri tekrarlayarak zorlukla konuşmak","e1":"\"I","e1t":"I","e2":"I don't know,\" he stammered.","e2t":"\"B"},{"w":"standardize / standardise","tr":"standartlaştırmak / tek tipleştirmek","te":"Verb","tt":"Fiil","de":"To make things of the same type all have the same features","dt":"Aynı türdeki şeylerin aynı özelliklere sahip olmasını sağlamak","e1":"We need to standardize the design of our apps.","e1t":"Uygulamalarımızın tasarımını standartlaştırmalıyız.","e2":"Standardized testing.","e2t":"Standartlaştırılmış sınavlar."},{"w":"standpoint","tr":"bakış açısı / görüş noktası","te":"Noun","tt":"İsim","de":"A set of beliefs or ideas from which opinions are formed","dt":"Görüşlerin oluşturulduğu inanç veya fikirler bütünü","e1":"From a practical standpoint...","e1t":"Pratik bir bakış açısıyla...","e2":"From a financial standpoint.","e2t":"Mali açıdan (bakış açısıyla)."},{"w":"staple","tr":"temel gıda / zımba / zımbalamak / başlıca","te":"Noun/Verb/Adj","tt":"A basic food; or a small wire used to join papers","de":"Temel gıda; veya kağıtları birleştirmek için kullanılan tel","dt":"Rice is a staple food in Asia.","e1":"Pirinç, Asya'da temel gıdadır.","e1t":"A staple of the community.","e2":"Toplumun temel direği.","e2t":""},{"w":"stapler","tr":"zımba (alet)","te":"Noun","tt":"İsim","de":"A tool used for putting staples into paper","dt":"Kağıda zımba teli takmak için kullanılan alet","e1":"Can I borrow your stapler?","e1t":"Zımbanı ödünç alabilir miyim?","e2":"Heavy","e2t":"duty stapler."},{"w":"starchy","tr":"nişastalı / resmi (tavır) / sertleşmiş","te":"Adjective","tt":"Sıfat","de":"(Of food) containing a lot of starch","dt":"(Yiyecek için) çok nişasta içeren","e1":"Potatoes and pasta are starchy foods.","e1t":"Patates ve makarna nişastalı yiyeceklerdir.","e2":"A starchy manner (formal and stiff).","e2t":"Resmi ve mesafeli bir tavır."},{"w":"stark","tr":"tam / kesin / çıplak / sert","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Empty or without decoration; or very clear (difference)","dt":"Boş veya süssüz; veya çok net (fark)","e1":"The stark reality of the situation.","e1t":"Durumun çıplak (acı) gerçeği.","e2":"In stark contrast to...","e2t":"... ile tam bir tezat içinde."},{"w":"startle","tr":"ürkütmek / şaşırtmak / korkutmak","te":"Verb","tt":"Fiil","de":"To surprise someone suddenly","dt":"Birini aniden şaşırtmak (korkutmak)","e1":"The loud noise startled me.","e1t":"Yüksek ses beni ürküttü.","e2":"You startled me!","e2t":"Beni korkuttun (aniden karşıma çıktın)!"},{"w":"statesman","tr":"devlet adamı","te":"Noun","tt":"İsim","de":"An important and experienced politician","dt":"Önemli ve deneyimli siyasetçi","e1":"A respected senior statesman.","e1t":"Saygın bir kıdemli devlet adamı.","e2":"The qualities of a great statesman.","e2t":"Büyük bir devlet adamının vasıfları."},{"w":"static","tr":"statik / durgun / parazit (radyo)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not moving or changing; or noise on a radio","dt":"Hareket etmeyen veya değişmeyen; veya radyodaki gürültü","e1":"Static electricity.","e1t":"Statik elektrik.","e2":"Prices have remained static.","e2t":"Fiyatlar sabit (durgun) kaldı."},{"w":"stationary","tr":"hareketsiz / sabit / duran","te":"Adjective","tt":"Sıfat","de":"Not moving or not intended to be moved","dt":"Hareket etmeyen veya hareket etmesi amaçlanmayan","e1":"A stationary vehicle.","e1t":"Duran (hareketsiz) bir araç.","e2":"The sun is stationary relative to the planets.","e2t":"Güneş, gezegenlere göre sabittir."},{"w":"stationery","tr":"kırtasiye / yazı gereçleri","te":"Noun","tt":"İsim","de":"Paper, envelopes, and other materials for writing","dt":"Kağıt, zarf ve diğer yazım gereçleri","e1":"To buy office stationery.","e1t":"Ofis kırtasiyesi almak.","e2":"Personalized stationery.","e2t":"Kişiselleştirilmiş yazı kağıdı."},{"w":"statistics","tr":"istatistik / veri","te":"Noun","tt":"İsim","de":"A collection of facts in the form of numbers","dt":"Sayılar halindeki gerçekler bütünü","e1":"Statistics show that crime is falling.","e1t":"İstatistikler suçun azaldığını gösteriyor.","e2":"Official statistics.","e2t":"Resmi istatistikler."},{"w":"statue","tr":"heykel / heykelcik","te":"Noun/Verb","tt":"İsim/Fiil","de":"An object made from a hard material to look like a person","dt":"Bir kişiye benzemesi için sert malzemeden yapılmış nesne","e1":"The Statue of Liberty.","e1t":"Özgürlük Heykeli.","e2":"To erect a statue.","e2t":"Heykel dikmek."},{"w":"stature","tr":"boy / endam / mevki / itibar","te":"Noun","tt":"İsim","de":"The height of a person; or the importance of someone","dt":"Bir kişinin boyu; veya birinin önemi (itibarı)","e1":"A woman of small stature.","e1t":"Kısa boylu bir kadın.","e2":"An artist of international stature.","e2t":"Uluslararası itibara sahip bir sanatçı."},{"w":"statute","tr":"tüzük / yasa / kanun","te":"Noun","tt":"İsim","de":"A written law passed by a legislative body","dt":"Yasama organı tarafından çıkarılan yazılı kanun","e1":"Penal statute.","e1t":"Ceza yasası.","e2":"Under the statutes of the university.","e2t":"Üniversite tüzüğüne göre."},{"w":"steadfast","tr":"sadık / kararlı / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"Not changing your opinions or actions","dt":"Görüşlerini veya eylemlerini değiştirmeyen","e1":"He remained steadfast in his belief.","e1t":"İnancında kararlı kaldı.","e2":"Steadfast support.","e2t":"Sarsılmaz destek."},{"w":"steady","tr":"istikrarlı / sabit / düzenli / dengelemek","te":"Adjective/Adv/Noun/Verb","tt":"Developing or happening in a smooth, regular way","de":"Sorunsuz ve düzenli bir şekilde gelişen/gerçekleşen","dt":"A steady increase in prices.","e1":"Fiyatlarda düzenli (istikrarlı) bir artış.","e1t":"Keep the camera steady.","e2":"Kamerayı sabit tut.","e2t":""},{"w":"steak","tr":"biftek / fileto","te":"Noun","tt":"İsim","de":"A thick slice of high","dt":"quality meat or fish","e1":"Yüksek kaliteli et veya balığın kalın dilimi","e1t":"A medium","e2":"rare steak.","e2t":"Orta"},{"w":"stealth","tr":"gizlilik / sinsi / radara yakalanmayan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A quiet and secret way of moving or behaving","dt":"Sessiz ve gizli hareket etme veya davranma biçimi","e1":"He moved with the stealth of a cat.","e1t":"Bir kedinin gizliliğiyle hareket etti.","e2":"Stealth aircraft.","e2t":"Hayalet (radara yakalanmayan) uçak."},{"w":"steam","tr":"buhar / buharlaşmak / hırs / güç","te":"Noun/Verb","tt":"İsim/Fiil","de":"The gas that water forms when it boils","dt":"Su kaynadığında oluşan gaz","e1":"Steam engine.","e1t":"Buhar makinesi.","e2":"To cook vegetables in steam.","e2t":"Sebzeleri buharda pişirmek."},{"w":"steel","tr":"çelik / güçlendirmek / metanet","te":"Noun/Adj/Verb","tt":"A strong metal made from iron and carbon","de":"Demir ve karbondan yapılan güçlü metal","dt":"Stainless steel.","e1":"Paslanmaz çelik.","e1t":"Nerves of steel.","e2":"Çelik gibi sinirler.","e2t":""},{"w":"steep","tr":"dik / sarp / fahiş (fiyat) / ıslatmak","te":"Adjective/Noun/Verb","tt":"(Of a slope) rising or falling at a sharp angle","de":"(Yamaç için) keskin bir açıyla yükselen veya düşen","dt":"A steep hill.","e1":"Dik bir tepe.","e1t":"A steep rise in unemployment.","e2":"İşsizlikte keskin bir artış.","e2t":""},{"w":"steer","tr":"yönlendirmek / sürmek (gemi/araç) / dümen tutmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To control the direction of a vehicle","dt":"Bir aracın yönünü kontrol etmek","e1":"To steer a car.","e1t":"Araba sürmek (yönlendirmek).","e2":"To steer clear of someone (to avoid).","e2t":"Birinden uzak durmak."},{"w":"stellar","tr":"yıldızlarla ilgili / yıldız (başarılı)","te":"Adjective","tt":"Sıfat","de":"Relating to the stars; or very good or famous","dt":"Yıldızlarla ilgili; veya çok iyi/ünlü","e1":"Stellar evolution.","e1t":"Yıldız evrimi.","e2":"A stellar performance.","e2t":"Muhteşem (yıldızlara layık) bir performans."},{"w":"stem","tr":"gövde / sap /","te":"den gelmek / durdurmak","tt":"Noun/Verb","de":"İsim/Fiil","dt":"The long thin part of a plant; or to stop something","e1":"Bitkinin uzun ince kısmı; veya bir şeyi durdurmak","e1t":"Flower stem.","e2":"Çiçek sapı.","e2t":"The problem stems from a lack of trust."},{"w":"stereo","tr":"stereo / çift hoparlörlü ses","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A way of recording sound using two channels","dt":"İki kanal kullanarak ses kaydetme yolu","e1":"Stereo speakers.","e1t":"Stereo hoparlörler.","e2":"A car stereo.","e2t":"Araba teybi (müzik sistemi)."},{"w":"stereotype","tr":"klişe / basmakalıp örnek / kalıplaştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fixed idea about a particular type of person","dt":"Belirli bir kişi türü hakkındaki sabit (genellikle yanlış) fikir","e1":"Gender stereotypes.","e1t":"Cinsiyet kalıpları (klişeleri).","e2":"Cultural stereotypes.","e2t":"Kültürel klişeler."},{"w":"sterile","tr":"kısır / steril / verimsiz","te":"Adjective","tt":"Sıfat","de":"Not able to produce children; or completely clean","dt":"Çocuk sahibi olamayan; veya tamamen temiz","e1":"Sterile surgical instruments.","e1t":"Steril cerrahi aletler.","e2":"The land is sterile.","e2t":"Toprak verimsizdir."},{"w":"sterilize / sterilise","tr":"sterilize etmek / kısırlaştırmak","te":"Verb","tt":"Fiil","de":"To make something sterile","dt":"Bir şeyi steril hale getirmek (veya kısırlaştırmak)","e1":"To sterilize medical equipment.","e1t":"Tıbbi ekipmanı sterilize etmek.","e2":"To sterilize a dog.","e2t":"Bir köpeği kısırlaştırmak."},{"w":"stern","tr":"sert / ciddi / (geminin) kıç tarafı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Serious and strict; or the back of a ship","dt":"Ciddi ve sert/disiplinli; veya geminin arkası","e1":"A stern warning.","e1t":"Sert bir uyarı.","e2":"He gave me a stern look.","e2t":"Bana sert (ciddi) bir bakış attı."},{"w":"steward","tr":"kahya / görevli / (uçak/gemi) kabin görevlisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person whose job is to organize food or look after people","dt":"İşi yemek organize etmek veya insanlarla ilgilenmek olan görevli","e1":"Flight steward.","e1t":"Kabin görevlisi (steward).","e2":"Shop steward (union).","e2t":"Sendika temsilcisi."},{"w":"stick","tr":"sopa / yapıştırmak / saplamak / takılmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin piece of wood; or to join things with glue","dt":"İnce odun parçası; veya şeyleri tutkalla birleştirmek","e1":"To stick a label on a bottle.","e1t":"Şişeye etiket yapıştırmak.","e2":"To stick to the rules.","e2t":"Kurallara sadık kalmak."},{"w":"stiff","tr":"sert / kaskatı / zorlu / ceset (argo)","te":"Adjective/Adv/Noun","tt":"Firm and difficult to bend; or severe","de":"Sert ve bükülmesi zor; veya şiddetli","dt":"Stiff muscles.","e1":"Sertleşmiş kaslar.","e1t":"Stiff competition.","e2":"Zorlu rekabet.","e2t":""},{"w":"stifle","tr":"boğmak / bastırmak / engellemek","te":"Verb","tt":"Fiil","de":"To prevent something from happening; or to make it difficult to breathe","dt":"Bir şeyin olmasını engellemek; veya nefes almayı zorlaştırmak","e1":"To stifle a yawn.","e1t":"Esnemeyi bastırmak.","e2":"High taxes stifle economic growth.","e2t":"Yüksek vergiler ekonomik büyümeyi boğar (engeller)."},{"w":"stimulate","tr":"uyarmak / canlandırmak / teşvik etmek","te":"Verb","tt":"Fiil","de":"To encourage something to grow or become more active","dt":"Bir şeyin büyümesini veya daha aktif olmasını teşvik etmek","e1":"To stimulate the economy.","e1t":"Ekonomiyi canlandırmak.","e2":"Light stimulates plant growth.","e2t":"Işık bitki büyümesini uyarır."},{"w":"stimulus","tr":"uyarıcı / teşvik / dürtü","te":"Noun","tt":"İsim","de":"Something that causes a reaction or activity","dt":"Bir tepkiye veya faaliyete neden olan şey","e1":"Economic stimulus package.","e1t":"Ekonomik teşvik paketi.","e2":"Sensory stimulus.","e2t":"Duyusal uyarıcı."},{"w":"sting","tr":"sokmak / sızlamak / sokma / kazıklamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of an insect) to push a small sharp part into skin","dt":"(Böcek için) deriye keskin küçük bir parça sokmak","e1":"A bee stung me.","e1t":"Beni bir arı soktu.","e2":"To sting from a comment (to be hurt).","e2t":"Bir yorumdan dolayı incinmek (sızı duymak)."},{"w":"stingy","tr":"cimri / pinti / az","te":"Adjective","tt":"Sıfat","de":"Not generous with money","dt":"Para konusunda cömert olmayan","e1":"Don't be so stingy!","e1t":"Bu kadar cimri olma!","e2":"A stingy portion of food.","e2t":"Çok az (pinti) bir porsiyon yemek."},{"w":"stink","tr":"kötü kokmak / pis koku / berbat olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To have a very unpleasant smell","dt":"Çok nahoş kokmak","e1":"The rubbish stinks.","e1t":"Çöp pis kokuyor.","e2":"To raise a stink (to complain loudly).","e2t":"Olay çıkarmak (kıyameti koparmak)."},{"w":"stipulate","tr":"şart koşmak / belirtmek","te":"Verb","tt":"Fiil","de":"To state exactly what must be done","dt":"Tam olarak ne yapılması gerektiğini belirtmek (şart koşmak)","e1":"The contract stipulates that the work must be finished by June.","e1t":"Sözleşme, işin Haziran'y kadar bitirilmesini şart koşuyor.","e2":"As stipulated in the agreement.","e2t":"Anlaşmada belirtildiği üzere."},{"w":"stir","tr":"karıştırmak / canlandırmak / kıpırdamak / heyecan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To mix a liquid by moving a spoon around; or to move","dt":"Kaşıkla sıvıyı karıştırmak; veya hareket etmek","e1":"Stir the sugar into your tea.","e1t":"Çayı şekere karıştır.","e2":"To stir up trouble.","e2t":"Sorun çıkarmak (kışkırtmak)."},{"w":"stitch","tr":"dikiş / dikiş atmak / batma (ağrı)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of thread used to join skin or cloth","dt":"Deriyi veya kumaşı birleştirmek için kullanılan iplik parçası","e1":"He needed ten stitches in his leg.","e1t":"Bacağına on dikiş atılması gerekti.","e2":"A stitch in time saves nine (proverb).","e2t":"Bugünün işini yarına bırakma."},{"w":"stock","tr":"stok / hisse senedi / et suyu / mevcut","te":"Noun/Verb/Adj","tt":"A supply of something; or part of a company","de":"Bir şeyin stoğu (arzı); veya bir şirketin parçası (hissesi)","dt":"Out of stock.","e1":"Stokta yok.","e1t":"Stock market.","e2":"Borsa.","e2t":""},{"w":"stocking","tr":"uzun çorap / kadın çorabı","te":"Noun","tt":"İsim","de":"A piece of clothing that fits tightly over the leg","dt":"Bacağı sıkıca saran giysi parçası","e1":"Nylon stockings.","e1t":"Naylon çoraplar.","e2":"Christmas stocking.","e2t":"Noel çorabı."},{"w":"stony","tr":"taşlı / hissiz / duygusuz","te":"Adjective","tt":"Sıfat","de":"Covered with stones; or showing no emotion","dt":"Taşlarla kaplı; veya hiç duygu göstermeyen","e1":"A stony path.","e1t":"Taşlı bir yol.","e2":"She gave him a stony look.","e2t":"Ona duygusuz (sert) bir bakış attı."},{"w":"stool","tr":"tabure / dışkı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A seat that has no back or arms; or waste from the body","dt":"Arkalığı veya kolçağı olmayan koltuk; veya vücut atığı","e1":"To sit on a high stool.","e1t":"Yüksek bir tabureye oturmak.","e2":"Stool sample (medical).","e2t":"Dışkı örneği."},{"w":"stoop","tr":"eğilmek / kambur durmak / tenezzül etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To bend your body forward and down","dt":"Vücudu öne ve aşağı doğru eğmek","e1":"He stooped to pick up the coin.","e1t":"Bozuk parayı almak için eğildi.","e2":"To stoop to lying.","e2t":"Yalan söylemeye tenezzül etmek."},{"w":"storage","tr":"depolama / depo / saklama","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The act of keeping things for future use","dt":"Şeyleri gelecek kullanım için saklama eylemi","e1":"Data storage.","e1t":"Veri depolama.","e2":"Cold storage.","e2t":"Soğuk hava deposu."},{"w":"store","tr":"mağaza / dükkan / depolamak / stok","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large shop; or to keep something for future use","dt":"Büyük dükkan; veya bir şeyi gelecek kullanım için saklamak","e1":"Department store.","e1t":"Katlı mağaza.","e2":"To store information on a computer.","e2t":"Bilgisayarda bilgi depolamak."},{"w":"stout","tr":"sağlam / iri yarı / cesur / bir tür bira","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a person) fat or heavy; or strong and thick","dt":"(Kişi için) kilolu veya ağır; veya güçlü ve kalın","e1":"A stout old man.","e1t":"İri yarı yaşlı bir adam.","e2":"Stout shoes.","e2t":"Sağlam ayakkabılar."},{"w":"stove","tr":"ocak / soba","te":"Noun","tt":"İsim","de":"A piece of equipment for cooking or heating a room","dt":"Yemek pişirmek veya odayı ısıtmak için kullanılan araç","e1":"A gas stove.","e1t":"Gazlı ocak.","e2":"Put the kettle on the stove.","e2t":"Çaydanlığı ocağın üzerine koy."},{"w":"strain","tr":"gerinim / zorlanma / tür / süzmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A force that pulls or stretches; or a type of disease","dt":"Çeken veya geren güç; veya bir hastalık türü","e1":"To suffer from muscle strain.","e1t":"Kas zorlanmasından (incinmesinden) muzdarip olmak.","e2":"A new strain of the virus.","e2t":"Virüsün yeni bir türü (varyantı)."},{"w":"strand","tr":"tel / iplikçik / sahil / mahsur bırakmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A single thin piece of hair or wire; or to leave someone in a difficult place","dt":"Saç veya telin tek bir ince parçası; veya birini zor durumda bırakmak","e1":"A strand of hair.","e1t":"Bir saç teli.","e2":"Hundreds of passengers were stranded at the airport.","e2t":"Yüzlerce yolcu havaalanında mahsur kaldı."},{"w":"strap","tr":"kayış / kordon / bağlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A narrow strip of leather or cloth used for fastening","dt":"Bağlamak için kullanılan dar deri veya kumaş şerit","e1":"Watch strap.","e1t":"Saat kordonu.","e2":"Shoulder strap.","e2t":"Omuz askısı."},{"w":"strategic","tr":"stratejik / hayati","te":"Adjective","tt":"Sıfat","de":"Helping to achieve a plan, especially in business or war","dt":"Bir planın başarılmasına yardımcı olan, özellikle iş veya savaşta","e1":"A strategic decision.","e1t":"Stratejik bir karar.","e2":"Of strategic importance.","e2t":"Stratejik öneme sahip."},{"w":"stratosphere","tr":"stratosfer","te":"Noun","tt":"İsim","de":"The layer of the Earth's atmosphere above the troposphere","dt":"Dünya atmosferinin troposfer üzerindeki tabakası","e1":"Most commercial jets fly in the lower stratosphere.","e1t":"Çoğu ticari jet alt stratosferde uçar.","e2":"Ozone is found in the stratosphere.","e2t":"Ozon stratosferde bulunur."},{"w":"stray","tr":"başıboş / yolunu kaybetmiş / sapmak","te":"Adjective/Noun/Verb","tt":"(Of an animal) having no home; or to move away from a place","de":"(Hayvan için) evi olmayan; veya bir yerden uzaklaşmak (sapmak)","dt":"A stray dog.","e1":"Başıboş (sahipsiz) bir köpek.","e1t":"To stray from the subject.","e2":"Konudan sapmak.","e2t":""},{"w":"streak","tr":"çizgi / damar / huy / seri / hızla gitmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long thin mark; or a part of someone's character","dt":"Uzun ince iz; veya birinin karakterinin bir parçası","e1":"A streak of lightning.","e1t":"Bir şimşek çakması (hattı).","e2":"A mean streak.","e2t":"Kötü (cimri) bir huy."},{"w":"streamline","tr":"modernize etmek / düzene koymak / aerodinamik hale getirmek","te":"Verb/Adjective","tt":"To make a process more efficient; or to give a smooth shape","de":"Bir süreci daha verimli hale getirmek; veya düzgün bir şekil vermek","dt":"To streamline the production process.","e1":"Üretim sürecini düzene koymak (basitleştirmek).","e1t":"A streamlined car design.","e2":"Aerodinamik (akıcı) bir araba tasarımı.","e2t":""},{"w":"strenuous","tr":"yorucu / ağır / çetin","te":"Adjective","tt":"Sıfat","de":"Needing a lot of physical or mental effort","dt":"Çok fazla fiziksel veya zihinsel çaba gerektiren","e1":"Strenuous exercise.","e1t":"Yorucu (ağır) egzersiz.","e2":"To make a strenuous effort.","e2t":"Çetin (yoğun) bir çaba sarf etmek."},{"w":"stress","tr":"stres / vurgu / vurgulamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great worry; or special importance given to something","dt":"Büyük endişe; veya bir şeye verilen özel önem","e1":"To be under a lot of stress.","e1t":"Büyük stres altında olmak.","e2":"To lay stress on something.","e2t":"Bir şeyi vurgulamak (üzerine basmak)."},{"w":"stretch","tr":"esnemek / uzanmak / germek / süre / alan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make something longer or wider by pulling","dt":"Bir şeyi çekerek uzatmak veya genişletmek","e1":"To stretch your muscles.","e1t":"Kaslarını germek (esnetmek).","e2":"A long stretch of road.","e2t":"Uzun bir yol şeridi (alanı)."},{"w":"stricken","tr":"uğramış / yakalanmış / tutulmuş","te":"Adjective","tt":"Sıfat","de":"Suffering severely from the effects of something","dt":"Bir şeyin etkilerinden ağır bir şekilde muzdarip olan","e1":"Poverty","e1t":"stricken areas.","e2":"Yoksulluğun pençesindeki (yoksul) bölgeler.","e2t":"Panic"},{"w":"strict","tr":"katı / sert / sıkı / tam","te":"Adjective","tt":"Sıfat","de":"Following rules exactly; or severe","dt":"Kurallara tam olarak uyan; veya sert","e1":"My parents were very strict.","e1t":"Ailem çok katıydı (disiplinliydi).","e2":"In the strict sense of the word.","e2t":"Kelimenin tam (dar) anlamıyla."},{"w":"stride","tr":"uzun adım / ilerleme / uzun adımlarla yürümek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long step; or an important positive development","dt":"Uzun adım; veya önemli olumlu gelişme","e1":"To take something in your stride.","e1t":"Bir şeyi soğukkanlılıkla karşılamak (üstesinden gelmek).","e2":"To make great strides in medicine.","e2t":"Tıpta büyük ilerlemeler kaydetmek."},{"w":"strife","tr":"çatışma / çekişme / kavga","te":"Noun","tt":"İsim","de":"Violent or angry disagreement","dt":"Şiddetli veya öfkeli anlaşmazlık","e1":"Civil strife.","e1t":"İç karışıklık (çatışma).","e2":"Political strife.","e2t":"Siyasi çekişme."},{"w":"strike","tr":"grev / vurmak / çarpmak / dikkatini çekmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To refuse to work as a protest; or to hit","dt":"Protesto olarak çalışmayı reddetmek; veya vurmak","e1":"To go on strike.","e1t":"Greve gitmek.","e2":"The ship struck a rock.","e2t":"Gemi bir kayaya çarptı."},{"w":"striking","tr":"çarpıcı / dikkat çekici / şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Very unusual or easily noticed","dt":"Çok sıra dışı veya kolayca fark edilen","e1":"A striking resemblance.","e1t":"Çarpıcı bir benzerlik.","e2":"Striking features.","e2t":"Dikkat çekici (güzel) yüz hatları."},{"w":"string","tr":"ip / sicim / tel (enstrüman) / dizi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thin rope; or a set of similar things","dt":"İnce ip; veya benzer şeyler dizisi","e1":"To tie a parcel with string.","e1t":"Bir paketi sicimle bağlamak.","e2":"Guitar strings.","e2t":"Gitar telleri."},{"w":"stringent","tr":"sıkı / katı / zorlayıcı","te":"Adjective","tt":"Sıfat","de":"(Of a rule/condition) very strict","dt":"(Kural/koşul için) çok sıkı","e1":"Stringent safety regulations.","e1t":"Sıkı güvenlik düzenlemeleri.","e2":"Stringent economic measures.","e2t":"Sert (zorlayıcı) ekonomik önlemler."},{"w":"strip","tr":"soymak / çıkarmak / şerit / çizgi roman","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove your clothing; or a long narrow piece","dt":"Kıyafetlerini çıkarmak; veya uzun dar parça","e1":"To strip naked.","e1t":"Çırılçıplak soyunmak.","e2":"A strip of land.","e2t":"Bir toprak şeridi."},{"w":"strive","tr":"çabalamak / uğraşmak / azmetmek","te":"Verb","tt":"Fiil","de":"To try very hard to achieve something","dt":"Bir şeyi başarmak için çok çabalamak","e1":"To strive for excellence.","e1t":"Mükemmellik için çabalamak.","e2":"We must strive to improve.","e2t":"Gelişmek için uğraşmalıyız."},{"w":"stroke","tr":"felç / inme / vuruş / okşamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden serious illness in the brain; or a hit","dt":"Beyinde ani ciddi hastalık; veya vuruş","e1":"He suffered a stroke.","e1t":"Felç geçirdi.","e2":"To stroke a cat.","e2t":"Bir kediyi okşamak."},{"w":"stroll","tr":"gezinti / yavaşça yürümek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk in a slow, relaxed way","dt":"Yavaş, rahat bir şekilde yürümek","e1":"We strolled along the beach.","e1t":"Plajda gezindik.","e2":"To go for a stroll.","e2t":"Gezintiye çıkmak."},{"w":"structural","tr":"yapısal","te":"Adjective","tt":"Sıfat","de":"Relating to the way something is built or organized","dt":"Bir şeyin inşa edilme veya organize edilme şekliyle ilgili","e1":"Structural changes in the economy.","e1t":"Ekonomideki yapısal değişiklikler.","e2":"Structural damage.","e2t":"Yapısal hasar."},{"w":"structure","tr":"yapı / bünye / inşa etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The way that parts of something are put together","dt":"Bir şeyin parçalarının bir araya getirilme şekli","e1":"The structure of a sentence.","e1t":"Cümle yapısı.","e2":"Social structure.","e2t":"Sosyal yapı."},{"w":"stubborn","tr":"inatçı / dikbaşlı","te":"Adjective","tt":"Sıfat","de":"Refusing to change your ideas or stop doing something","dt":"Fikirlerini değiştirmeyi veya bir şeyi yapmayı bırakmayı reddeden","e1":"He is very stubborn.","e1t":"O çok inatçıdır.","e2":"A stubborn problem (difficult to solve).","e2t":"İnatçı (çözümü zor) bir sorun."},{"w":"studio","tr":"stüdyo / atölye / tek odalı daire","te":"Noun","tt":"İsim","de":"A room where an artist works or a movie is made","dt":"Sanatçının çalıştığı veya film yapılan oda","e1":"Recording studio.","e1t":"Kayıt stüdyosu.","e2":"A studio apartment.","e2t":"Stüdyo daire (tek odalı)."},{"w":"stuff","tr":"şey / madde / tıkıştırmak / doldurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Used to refer to a substance or a group of things","dt":"Bir maddeye veya bir grup şeye atıfta bulunmak için kullanılır","e1":"What is this oily stuff?","e1t":"Bu yağlı şey nedir?","e2":"To stuff a turkey.","e2t":"Bir hindiyi doldurmak."},{"w":"stuffy","tr":"havasız / basık / resmi ve sıkıcı","te":"Adjective","tt":"Sıfat","de":"Lacking fresh air; or old","dt":"fashioned and boring","e1":"Taze hava eksikliği olan; veya eski moda ve sıkıcı","e1t":"A stuffy room.","e2":"Havasız bir oda.","e2t":"A stuffy academic debate."},{"w":"stumble","tr":"tökezlemek / sendelemek / rastlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To step awkwardly and almost fall","dt":"Sakarca adım atıp neredeyse düşmek","e1":"He stumbled on a rock.","e1t":"Bir kayaya tökezledi.","e2":"To stumble across an old friend (to meet by chance).","e2t":"Eski bir arkadaşa tesadüfen rastlamak."},{"w":"stump","tr":"kütük / ağaç kökü / zor durumda bırakmak / (politika) gezmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The bottom part of a tree left in the ground","dt":"Toprakta kalan ağaç kökü","e1":"To sit on a tree stump.","e1t":"Bir ağaç kütüğünün üzerine oturmak.","e2":"This question really stumped me.","e2t":"Bu soru beni gerçekten zor durumda bıraktı (çözemedim)."},{"w":"stun","tr":"şoke etmek / sersemletmek / bayıltmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shock or surprise someone very much","dt":"Birini çok şok etmek veya şaşırtmak","e1":"I was stunned by the news.","e1t":"Haberler karşısında şoke oldum.","e2":"To stun an animal.","e2t":"Bir hayvanı sersemletmek (bayıltmak)."},{"w":"stunt","tr":"akrobasi / numara / (büyümeyi) engellemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something dangerous done to entertain people","dt":"İnsanları eğlendirmek için yapılan tehlikeli şey","e1":"A publicity stunt.","e1t":"Reklam numarası (gösterisi).","e2":"Stunt man.","e2t":"Dublör."},{"w":"stupendous","tr":"muazzam / şaşırtıcı / devasa","te":"Adjective","tt":"Sıfat","de":"Very large or impressive","dt":"Çok büyük veya etkileyici","e1":"A stupendous achievement.","e1t":"Muazzam (şaşırtıcı) bir başarı.","e2":"Stupendous news.","e2t":"Harika (şaşırtıcı) haberler."},{"w":"sturdy","tr":"sağlam / dayanıklı / gürbüz","te":"Adjective","tt":"Sıfat","de":"Physically strong and solid","dt":"Fiziksel olarak güçlü ve sağlam","e1":"A sturdy table.","e1t":"Sağlam bir masa.","e2":"Sturdy boots.","e2t":"Dayanıklı botlar."},{"w":"style","tr":"tarz / üslup / biçim / şekil vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular way of doing something","dt":"Bir şeyi yapmanın belirli yolu","e1":"Life style.","e1t":"Yaşam tarzı.","e2":"Writing style.","e2t":"Yazım üslubu."},{"w":"subdivide","tr":"alt bölümlere ayırmak","te":"Verb","tt":"Fiil","de":"To divide something into smaller parts","dt":"Bir şeyi daha küçük parçalara bölmek","e1":"The office was subdivided into smaller cubicles.","e1t":"Ofis daha küçük bölmelere ayrıldı.","e2":"To subdivide land.","e2t":"Araziyi parsellere (alt bölümlere) ayırmak."},{"w":"subdue","tr":"bastırmak / zapt etmek / hafifletmek","te":"Verb","tt":"Fiil","de":"To use force to take control of something","dt":"Bir şeyin kontrolünü ele geçirmek için güç kullanmak","e1":"To subdue a rebellion.","e1t":"Bir isyanı bastırmak.","e2":"She managed to subdue her fears.","e2t":"Korkularını yenmeyi (zapt etmeyi) başardı."},{"w":"subjective","tr":"öznel / subjektif","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Influenced by personal feelings or opinions","dt":"Kişisel duygu veya görüşlerden etkilenen","e1":"A subjective opinion.","e1t":"Öznel (kişisel) bir görüş.","e2":"Beauty is subjective.","e2t":"Güzellik özneldir (kişiden kişiye değişir)."},{"w":"submarine","tr":"denizaltı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A ship that can travel underwater","dt":"Suyun altında gidebilen gemi","e1":"To serve on a submarine.","e1t":"Bir denizaltıda görev yapmak.","e2":"Submarine cables.","e2t":"Denizaltı kabloları."},{"w":"submerge","tr":"batırmak / suya daldırmak / su altında kalmak","te":"Verb","tt":"Fiil","de":"To put something under the surface of water","dt":"Bir şeyi su yüzeyinin altına koymak","e1":"The town was submerged by the flood.","e1t":"Kasaba sel suları altında kaldı.","e2":"To submerge a submarine.","e2t":"Bir denizaltıyı dalışa geçirmek (suya daldırmak)."},{"w":"submission","tr":"boyun eğme / sunma / teslim","te":"Noun","tt":"İsim","de":"The act of accepting that someone has power over you","dt":"Birinin üzerinizde gücü olduğunu kabul etme eylemi","e1":"To starve someone into submission.","e1t":"Birini aç bırakarak teslim olmaya zorlamak.","e2":"Deadline for the submission of reports.","e2t":"Raporların sunulması (teslimi) için son tarih."},{"w":"subordinate","tr":"ast / ikincil / alt rütbeli","te":"Adjective/Noun/Verb","tt":"Lower in rank or importance","de":"Rütbe veya önem bakımından daha düşük","dt":"To treat your subordinates with respect.","e1":"Astlarınıza saygıyla davranmak.","e1t":"A subordinate clause (grammar).","e2":"Yan cümlecik.","e2t":""},{"w":"subscribe","tr":"abone olmak / katılmak (fikre) / bağış yapmak","te":"Verb","tt":"Fiil","de":"To pay money to receive a service regularly","dt":"Bir hizmeti düzenli almak için para ödemek","e1":"To subscribe to a magazine.","e1t":"Bir dergiye abone olmak.","e2":"I don't subscribe to that theory.","e2t":"O teoriye katılmıyorum."},{"w":"subsequent","tr":"sonraki / izleyen","te":"Adjective","tt":"Sıfat","de":"Happening after something else","dt":"Başka bir şeyden sonra olan","e1":"Subsequent events proved him right.","e1t":"Sonraki olaylar onu haklı çıkardı.","e2":"Subsequent to the meeting.","e2t":"Toplantıdan sonra."},{"w":"subside","tr":"hafiflemek / azalmak / çökmek (toprak)","te":"Verb","tt":"Fiil","de":"To become less strong or return to a normal level","dt":"Daha az güçlü hale gelmek veya normal seviyeye dönmek","e1":"The pain began to subside.","e1t":"Ağrı hafiflemeye başladı.","e2":"The storm finally subsided.","e2t":"Fırtına sonunda dindi."},{"w":"subsidiary","tr":"bağlı şirket / yan / destekleyici","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A company that is owned by a larger company","dt":"Daha büyük bir şirkete ait olan şirket","e1":"A subsidiary of a multinational corporation.","e1t":"Çok uluslu bir şirketin bağlı kuruluşu.","e2":"A subsidiary issue.","e2t":"Yan (ikincil) bir mesele."},{"w":"subsidy","tr":"sübvansiyon / devlet desteği / yardım","te":"Noun","tt":"İsim","de":"Money given by a government to help pay for something","dt":"Bir şeyin ödenmesine yardımcı olmak için hükümet tarafından verilen para","e1":"Agricultural subsidies.","e1t":"Tarımsal sübvansiyonlar (destekler).","e2":"To provide a subsidy for public transport.","e2t":"Toplu taşıma için destek sağlamak."},{"w":"subsist","tr":"geçinmek / varlığını sürdürmek","te":"Verb","tt":"Fiil","de":"To get enough food or money to stay alive","dt":"Hayatta kalmak için yeterli gıda veya parayı sağlamak","e1":"They subsist on a diet of rice and vegetables.","e1t":"Pirinç ve sebze diyetiyle geçiniyorlar.","e2":"To subsist on a small income.","e2t":"Küçük bir gelirle geçinmek."},{"w":"substance","tr":"madde / töz / içerik / varlık","te":"Noun","tt":"İsim","de":"A particular type of matter; or the most important part of something","dt":"Belirli bir madde türü; veya bir şeyin en önemli kısmı","e1":"A sticky substance.","e1t":"Yapışkan bir madde.","e2":"There is no substance to these rumors.","e2t":"Bu söylentilerin bir içeriği (dayanağı) yok."},{"w":"substantial","tr":"önemli / azımsanmayacak / sağlam","te":"Adjective","tt":"Sıfat","de":"Large in size, value, or importance","dt":"Boyut, değer veya önem bakımından büyük","e1":"A substantial amount of money.","e1t":"Önemli (büyük) miktarda para.","e2":"Substantial progress has been made.","e2t":"Azımsanmayacak (önemli) ilerleme kaydedildi."},{"w":"substitute","tr":"yedek / vekil / yerine geçirmek / yerine kullanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person or thing that takes the place of another","dt":"Başkasının yerini alan kişi veya şey","e1":"A substitute teacher.","e1t":"Vekil (yedek) öğretmen.","e2":"You can substitute butter with margarine.","e2t":"Margarini tereyağı yerine kullanabilirsiniz."},{"w":"subtle","tr":"ince / hemen fark edilmeyen / kurnazca","te":"Adjective","tt":"Sıfat","de":"Not loud, bright, or obvious; or small but important","dt":"Yüksek sesli, parlak veya bariz olmayan; veya küçük ama önemli","e1":"A subtle difference in color.","e1t":"Renkteki ince (hafif) bir fark.","e2":"Subtle hints.","e2t":"Üstü kapalı (ince) ipuçları."},{"w":"subtraction","tr":"çıkarma (işlemi)","te":"Noun","tt":"İsim","de":"The process of taking a number away from another","dt":"Bir sayıyı diğerinden çıkarma işlemi","e1":"Addition and subtraction.","e1t":"Toplama ve çıkarma.","e2":"To perform a simple subtraction.","e2t":"Basit bir çıkarma işlemi yapmak."},{"w":"suburb","tr":"banliyö / şehir dışı / mahalle","te":"Noun","tt":"İsim","de":"An area where people live that is outside the center of a city","dt":"Şehir merkezinin dışındaki yerleşim alanı","e1":"He lives in a suburb of London.","e1t":"Londra'nın bir banliyösünde yaşıyor.","e2":"Suburban life.","e2t":"Şehir dışı (banliyö) hayatı."},{"w":"subversive","tr":"yıkıcı / baltalayıcı / devrimci","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Trying to destroy or damage an established system","dt":"Kurulu bir sistemi yok etmeye veya zarar vermeye çalışan","e1":"Subversive activities.","e1t":"Yıkıcı faaliyetler.","e2":"A subversive book.","e2t":"Sistemi eleştiren (baltalayıcı) bir kitap."},{"w":"subway","tr":"metro (ABD) / alt geçit (UK)","te":"Noun","tt":"İsim","de":"An underground railway system; or a path under a road","dt":"Yer altı demiryolu sistemi; veya yol altındaki yaya yolu","e1":"To take the subway to work.","e1t":"İşe gitmek için metroyu kullanmak.","e2":"A pedestrian subway.","e2t":"Yaya alt geçidi."},{"w":"succession","tr":"ardıllık / silsile / yerine geçme / dizi","te":"Noun","tt":"İsim","de":"A number of similar things coming one after another","dt":"Birbiri ardına gelen benzer şeyler","e1":"A succession of failures.","e1t":"Bir dizi (silsile) başarısızlık.","e2":"The right of succession to the throne.","e2t":"Tahtın varisliği (yerine geçme) hakkı."},{"w":"successive","tr":"ardışık / art arda gelen","te":"Adjective","tt":"Sıfat","de":"Happening one after another","dt":"Birbiri ardına gerçekleşen","e1":"Successive victories.","e1t":"Üst üste gelen (ardışık) galibiyetler.","e2":"For the third successive year.","e2t":"Üçüncü yıl üst üste."},{"w":"successor","tr":"halef / varis / yerine gelen","te":"Noun","tt":"İsim","de":"A person who has a job after someone else","dt":"Birinden sonra o işi yapan kişi","e1":"He is the CEO's chosen successor.","e1t":"O, CEO'nun seçtiği halefidir (yerine gelecek kişidir).","e2":"A worthy successor.","e2t":"Layık bir halef."},{"w":"succulent","tr":"sulu / lezzetli / etli bitki","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of food) full of juice and tasting good; or a type of plant","dt":"(Yemek için) sulu ve tadı güzel; veya bir bitki türü","e1":"A succulent steak.","e1t":"Sulu (lezzetli) bir biftek.","e2":"Cacti are succulents.","e2t":"Kaktüsler etli (sulu) bitkilerdir."},{"w":"succumb","tr":"boyun eğmek / yenik düşmek / ölmek","te":"Verb","tt":"Fiil","de":"To stop trying to resist something; or to die from a disease","dt":"Bir şeye direnmeyi bırakmak; veya bir hastalıktan ölmek","e1":"To succumb to temptation.","e1t":"Günaha (baştan çıkarılmaya) yenik düşmek.","e2":"He succumbed to his injuries.","e2t":"Yaralarına yenik düştü (öldü)."},{"w":"suck","tr":"emmek / içine çekmek / berbat olmak (argo)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull liquid into your mouth; or to be very bad","dt":"Sıvıyı ağzına çekmek; veya çok kötü olmak","e1":"To suck a lollipop.","e1t":"Lolipop emmek.","e2":"The vacuum cleaner sucks up the dirt.","e2t":"Elektrikli süpürge kiri içine çeker."},{"w":"suffocate","tr":"boğulmak / boğmak / nefessiz kalmak","te":"Verb","tt":"Fiil","de":"To die or make someone die because they cannot breathe","dt":"Nefes alamadığı için ölmek veya birini öldürmek","e1":"He suffocated in the smoke.","e1t":"Dumandan boğuldu.","e2":"The heat was suffocating.","e2t":"Sıcaklık boğucuydu."},{"w":"suffrage","tr":"oy hakkı","te":"Noun","tt":"İsim","de":"The right to vote in an election","dt":"Seçimlerde oy kullanma hakkı","e1":"Women's suffrage.","e1t":"Kadınların oy hakkı.","e2":"Universal suffrage.","e2t":"Genel (evrensel) oy hakkı."},{"w":"suggestive","tr":"çağrıştıran / imalı / müstehcen","te":"Adjective","tt":"Sıfat","de":"Making you think of something; or relating to sex","dt":"Bir şeyi düşündüren; veya cinsellikle ilgili","e1":"The music is suggestive of a summer evening.","e1t":"Müzik bir yaz akşamını çağrıştırıyor.","e2":"Suggestive remarks.","e2t":"İmalı (müstehcen) sözler."},{"w":"suicide","tr":"intihar","te":"Noun/Verb/Adj","tt":"The act of intentionally killing oneself","de":"Birinin kendini kasten öldürme eylemi","dt":"To commit suicide.","e1":"İntihar etmek.","e1t":"A suicide bomber.","e2":"İntihar bombacısı.","e2t":""},{"w":"suite","tr":"süit (oda) / takım / set","te":"Noun","tt":"İsim","de":"A set of connected rooms; or a set of furniture/software","dt":"Birbirine bağlı odalar seti; veya mobilya/yazılım seti","e1":"A hotel suite.","e1t":"Otel süiti.","e2":"A suite of office programs.","e2t":"Ofis programları seti."},{"w":"sullen","tr":"somurtkan / asık suratlı / iç karartıcı","te":"Adjective","tt":"Sıfat","de":"Angry and unwilling to smile or be pleasant","dt":"Öfkeli ve gülümsemeye isteksiz","e1":"A sullen teenager.","e1t":"Somurtkan bir genç.","e2":"Sullen skies (dark and grey).","e2t":"Kasvetli (iç karartıcı) gökyüzü."},{"w":"sultry","tr":"sıcak ve nemli / şehvetli","te":"Adjective","tt":"Sıfat","de":"(Of weather) very hot and humid; or sexually attractive","dt":"(Hava için) çok sıcak ve nemli (basık); veya çekici","e1":"A sultry afternoon.","e1t":"Sıcak ve basık bir öğleden sonra.","e2":"A sultry voice.","e2t":"Şehvetli (buğulu) bir ses."},{"w":"summarize / summarise","tr":"özetlemek","te":"Verb","tt":"Fiil","de":"To give a short statement of the main points","dt":"Ana noktaların kısa bir ifadesini vermek","e1":"Can you summarize the main argument?","e1t":"Ana iddiayı özetleyebilir misin?","e2":"To summarize a story.","e2t":"Bir hikayeyi özetlemek."},{"w":"summary","tr":"özet / kısa ve öz","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A short statement of the main facts","dt":"Ana gerçeklerin kısa ifadesi","e1":"In summary...","e1t":"Özetle...","e2":"An executive summary.","e2t":"Yönetici özeti."},{"w":"summit","tr":"zirve / doruk / tepe","te":"Noun","tt":"İsim","de":"The highest point of a mountain; or an important meeting","dt":"Bir dağın en yüksek noktası; veya önemli toplantı","e1":"To reach the summit of Mt. Everest.","e1t":"Everest'in zirvesine ulaşmak.","e2":"A G7 summit meeting.","e2t":"G7 zirve toplantısı."},{"w":"summon","tr":"çağırmak / resmi olarak çağırmak / (cesaret vb.) toplamak","te":"Verb","tt":"Fiil","de":"To officially order someone to come; or to find a quality","dt":"Birine resmi olarak gelmesini emretmek; veya bir özelliği bulmak (toplamak)","e1":"He was summoned to appear in court.","e1t":"Mahkemeye çıkması için çağrıldı.","e2":"To summon the courage to speak.","e2t":"Konuşmak için cesaretini toplamak."},{"w":"sumptuous","tr":"lüks / görkemli / şatafatlı","te":"Adjective","tt":"Sıfat","de":"Very expensive and impressive","dt":"Çok pahalı ve etkileyici","e1":"A sumptuous feast.","e1t":"Görkemli (zengin) bir ziyafet.","e2":"Sumptuous palace decorations.","e2t":"Şatafatlı saray dekorasyonları."},{"w":"sundry","tr":"çeşitli / türlü / ufak tefek","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Various; of different kinds","dt":"Çeşitli; farklı türden","e1":"All and sundry (everyone).","e1t":"Herkes (çoluk çocuk/herkes).","e2":"Sundry items.","e2t":"Çeşitli (ufak tefek) eşyalar."},{"w":"superb","tr":"harika / mükemmel / şahane","te":"Adjective","tt":"Sıfat","de":"Of excellent quality; very good","dt":"Mükemmel kalitede; çok iyi","e1":"A superb performance.","e1t":"Harika bir performans.","e2":"The food was superb.","e2t":"Yemek şahaneydi."},{"w":"superficial","tr":"yüzeysel / üstünkörü","te":"Adjective","tt":"Sıfat","de":"Only on the surface; or not complete or deep","dt":"Sadece yüzeyde olan; veya tam/derin olmayan","e1":"A superficial wound.","e1t":"Yüzeysel bir yara.","e2":"Superficial knowledge.","e2t":"Üstünkörü (yüzeysel) bilgi."},{"w":"superfluous","tr":"gereksiz / fazlalık","te":"Adjective","tt":"Sıfat","de":"More than is needed; extra","dt":"Gerekenden fazla; ekstra","e1":"Superfluous details.","e1t":"Gereksiz (fazlalık) detaylar.","e2":"To remove superfluous words.","e2t":"Fazla kelimeleri çıkarmak."},{"w":"superintendent","tr":"müfettiş / emniyet müdürü / yönetici","te":"Noun","tt":"İsim","de":"A person who is in charge of a department or organization","dt":"Bir departman veya kuruluşun başındaki kişi","e1":"Police Superintendent.","e1t":"Emniyet Müdürü.","e2":"Schools Superintendent.","e2t":"Okullar Müfettişi (Müdürü)."},{"w":"superior","tr":"üstün / amir / kaliteli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Better than average or better than others","dt":"Ortalamadan veya diğerlerinden daha iyi","e1":"A superior product.","e1t":"Üstün (kaliteli) bir ürün.","e2":"To report to your superior.","e2t":"Amirinize rapor vermek."},{"w":"supernatural","tr":"doğaüstü","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Caused by forces that cannot be explained by science","dt":"Bilimle açıklanamayan güçlerin neden olduğu","e1":"Supernatural powers.","e1t":"Doğaüstü güçler.","e2":"A supernatural thriller.","e2t":"Doğaüstü (gizemli) gerilim filmi."},{"w":"supersede","tr":"yerine geçmek / yerini almak / eskittiği için değiştirmek","te":"Verb","tt":"Fiil","de":"To replace something older or less useful","dt":"Daha eski veya daha az yararlı olanın yerini almak","e1":"Most of these rules have been superseded.","e1t":"Bu kuralların çoğunun yerini yenileri aldı (eskidi).","e2":"Digital technology has superseded film.","e2t":"Dijital teknoloji filmin yerini aldı."},{"w":"superstition","tr":"batıl inanç","te":"Noun","tt":"İsim","de":"A belief that is not based on human reason or scientific knowledge","dt":"İnsan mantığına veya bilimsel bilgiye dayanmayan inanç","e1":"The superstition that black cats are unlucky.","e1t":"Kara kedilerin uğursuz olduğuna dair batıl inanç.","e2":"Old superstitions.","e2t":"Eski batıl inançlar."},{"w":"superstitious","tr":"batıl inançlı","te":"Adjective","tt":"Sıfat","de":"Believing in superstitions","dt":"Batıl inançlara inanan","e1":"I’m not superstitious, but I never walk under ladders.","e1t":"Batıl inançlı değilim ama asla merdiven altından geçmem.","e2":"A superstitious person.","e2t":"Batıl inançlı biri."},{"w":"supervise","tr":"denetlemek / gözetmek / yönetmek","te":"Verb","tt":"Fiil","de":"To be in charge of an activity or person","dt":"Bir faaliyetin veya kişinin başında olmak (izlemek)","e1":"She supervises a team of ten people.","e1t":"On kişilik bir ekibi denetliyor (yönetiyor).","e2":"To supervise the exams.","e2t":"Sınavları gözetmek."},{"w":"supervisor","tr":"danışman / şef / gözetmen","te":"Noun","tt":"İsim","de":"A person who is in charge of others","dt":"Başkalarından sorumlu olan kişi","e1":"Academic supervisor.","e1t":"Akademik danışman.","e2":"Floor supervisor.","e2t":"Kat şefi."},{"w":"supplement","tr":"takviye / ek / ilave etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that is added to improve or complete something","dt":"Bir şeyi geliştirmek veya tamamlamak için eklenen şey","e1":"Vitamin supplements.","e1t":"Vitamin takviyeleri.","e2":"To supplement your income.","e2t":"Gelirine ekleme yapmak (takviye etmek)."},{"w":"supplementary","tr":"tamamlayıcı / ek / ilave","te":"Adjective","tt":"Sıfat","de":"Added to something else in order to improve it","dt":"Bir şeyi geliştirmek için eklenen","e1":"Supplementary information.","e1t":"Ek (ilave) bilgi.","e2":"Supplementary budget.","e2t":"Ek bütçe."},{"w":"suppress","tr":"bastırmak / gizlemek / durdurmak","te":"Verb","tt":"Fiil","de":"To end something by force; or to prevent from being known","dt":"Bir şeyi zorla bitirmek; veya bilinmesini engellemek","e1":"To suppress a riot.","e1t":"Bir ayaklanmayı bastırmak.","e2":"To suppress the truth.","e2t":"Gerçeği gizlemek (bastırmak)."},{"w":"supreme","tr":"yüce / en yüksek / üstün","te":"Adjective","tt":"Sıfat","de":"Having the highest rank or level of importance","dt":"En yüksek rütbeye veya önem seviyesine sahip olan","e1":"The Supreme Court.","e1t":"Anayasa Mahkemesi (veya Yargıtay/Yüksek Mahkeme).","e2":"To make the supreme sacrifice (to die).","e2t":"En büyük fedakarlığı yapmak (canını vermek)."},{"w":"surcharge","tr":"ek ücret / sürşarj","te":"Noun/Verb","tt":"İsim/Fiil","de":"An extra amount of money that you have to pay","dt":"Ödemeniz gereken ek para miktarı","e1":"A fuel surcharge.","e1t":"Yakıt ek ücreti.","e2":"There is a 10% surcharge for late payment.","e2t":"Geç ödeme için %10 ek ücret vardır."},{"w":"surge","tr":"dalgalanma / ani yükseliş / kabarma / fırlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden large increase; or a strong movement of water","dt":"Ani büyük artış; veya suyun güçlü hareketi","e1":"A surge in energy prices.","e1t":"Enerji fiyatlarında ani yükseliş.","e2":"A power surge.","e2t":"Voltaj dalgalanması."},{"w":"surgeon","tr":"cerrah","te":"Noun","tt":"İsim","de":"A doctor who performs operations","dt":"Ameliyat yapan doktor","e1":"A heart surgeon.","e1t":"Kalp cerrahı.","e2":"He is a highly skilled surgeon.","e2t":"O çok yetenekli bir cerrahtır."},{"w":"surgery","tr":"ameliyat / cerrahi / muayenehane","te":"Noun","tt":"İsim","de":"The treatment of injuries by cutting open the body","dt":"Vücudu keserek yaralanmaların tedavisi","e1":"To undergo surgery.","e1t":"Ameliyat olmak.","e2":"Minor surgery.","e2t":"Küçük cerrahi müdahale."},{"w":"surmount","tr":"üstesinden gelmek / aşmak","te":"Verb","tt":"Fiil","de":"To deal with a difficulty successfully","dt":"Bir zorlukla başarıyla başa çıkmak","e1":"To surmount an obstacle.","e1t":"Bir engeli aşmak.","e2":"They managed to surmount all the difficulties.","e2t":"Tüm zorlukların üstesinden gelmeyi başardılar."},{"w":"surname","tr":"soyadı","te":"Noun","tt":"İsim","de":"The name you share with other members of your family","dt":"Ailenin diğer üyeleriyle paylaştığın isim","e1":"What is your surname?","e1t":"Soyadınız nedir?","e2":"To change your surname.","e2t":"Soyadını değiştirmek."},{"w":"surpass","tr":"aşmak / geçmek / üstün gelmek","te":"Verb","tt":"Fiil","de":"To do or be better than something else","dt":"Başka bir şeyden daha iyi olmak veya onu geçmek","e1":"The results surpassed all our expectations.","e1t":"Sonuçlar tüm beklentilerimizi aştı.","e2":"To surpass a record.","e2t":"Bir rekoru geçmek."},{"w":"surplus","tr":"fazlalık / artan miktar / bakiye","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An amount that is more than is needed","dt":"Gerekenden fazla olan miktar","e1":"Trade surplus.","e1t":"Ticaret fazlası.","e2":"Budget surplus.","e2t":"Bütçe fazlası."},{"w":"surrender","tr":"teslim olmak / vazgeçmek / teslim","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop fighting and admit defeat; or to give up a right","dt":"Savaşmayı bırakıp yenilgiyi kabul etmek; veya bir haktan vazgeçmek","e1":"The enemy soldiers surrendered.","e1t":"Düşman askerleri teslim oldu.","e2":"To surrender your passport.","e2t":"Pasaportunu teslim etmek."},{"w":"surround","tr":"çevrelemek / kuşatmak / etrafını sarmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be all around something","dt":"Bir şeyin her tarafında (etrafında) olmak","e1":"The house is surrounded by trees.","e1t":"Ev ağaçlarla çevrili.","e2":"Police surrounded the building.","e2t":"Polis binanın etrafını sardı."},{"w":"surroundings","tr":"çevre / civar / ortam","te":"Noun","tt":"İsim","de":"The place where someone or something is and the things in it","dt":"Birinin veya bir şeyin bulunduğu yer ve içindeki şeyler","e1":"To live in pleasant surroundings.","e1t":"Hoş bir çevrede yaşamak.","e2":"He adjusted quickly to his new surroundings.","e2t":"Yeni ortamına çabuk uyum sağladı."},{"w":"surveillance","tr":"gözetleme / takip / denetim","te":"Noun","tt":"İsim","de":"The careful watching of a person or place, especially by police","dt":"Bir kişinin veya yerin, özellikle polisçe, dikkatle izlenmesi","e1":"24","e1t":"hour video surveillance.","e2":"24 saat görüntülü gözetleme.","e2t":"To keep someone under surveillance."},{"w":"survey","tr":"anket / inceleme / ölçüm / araştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An examination of opinions made by asking people questions","dt":"İnsanlara sorular sorarak yapılan görüş incelemesi","e1":"To conduct a survey.","e1t":"Anket yürütmek (yapmak).","e2":"A recent survey shows that...","e2t":"Yakın tarihli bir anket gösteriyor ki..."},{"w":"survival","tr":"hayatta kalma / sağ kalma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The state of continuing to live or exist","dt":"Yaşamaya veya var olmaya devam etme durumu","e1":"Survival of the fittest.","e1t":"En güçlü olanın hayatta kalması.","e2":"A struggle for survival.","e2t":"Hayatta kalma mücadelesi."},{"w":"survive","tr":"hayatta kalmak / sağ çıkmak /","te":"den uzun yaşamak","tt":"Verb","de":"Fiil","dt":"To continue to live after a dangerous situation","e1":"Tehlikeli bir durumdan sonra yaşamaya devam etmek","e1t":"No one survived the plane crash.","e2":"Uçak kazasından kimse sağ çıkmadı.","e2t":"These plants can survive in the desert."},{"w":"susceptibility","tr":"duyarlılık / hassasiyet / savunmasızlık","te":"Noun","tt":"İsim","de":"The state of being easily influenced or affected by something","dt":"Bir şeyden kolayca etkilenme veya zarar görme durumu","e1":"Susceptibility to disease.","e1t":"Hastalığa karşı duyarlılık.","e2":"Genetic susceptibility.","e2t":"Genetik yatkınlık (hassasiyet)."},{"w":"susceptible","tr":"duyarlı / hassas / savunmasız / etkilenmeye açık","te":"Adjective","tt":"Sıfat","de":"Easily influenced or harmed by something","dt":"Bir şeyden kolayca etkilenen veya zarar gören","e1":"Children are more susceptible to the virus.","e1t":"Çocuklar virüse karşı daha hassastır (savunmasızdır).","e2":"Susceptible to flattery.","e2t":"Pohpohlanmaya müsait (açık)."},{"w":"suspect","tr":"şüphelenmek / şüpheli / sanık","te":"Verb/Noun/Adj","tt":"To think that someone has committed a crime","de":"Birinin suç işlediğini düşünmek","dt":"The police suspect him of murder.","e1":"Polis ondan cinayet şüphelisi olarak şüpheleniyor.","e1t":"A prime suspect.","e2":"Baş şüpheli.","e2t":""},{"w":"suspend","tr":"askıya almak / uzaklaştırmak / asmak","te":"Verb","tt":"Fiil","de":"To stop something temporarily; or to hang something","dt":"Bir şeyi geçici olarak durdurmak; veya bir şeyi asmak","e1":"The ferry service was suspended due to the storm.","e1t":"Feribot seferleri fırtına nedeniyle askıya alındı.","e2":"He was suspended from school.","e2t":"Okuldan (geçici olarak) uzaklaştırıldı."},{"w":"suspense","tr":"belirsizlik / merak / heyecanlı bekleyiş","te":"Noun","tt":"İsim","de":"A feeling of excitement or anxiety while waiting for something","dt":"Bir şeyi beklerken duyulan heyecan veya endişe hissi","e1":"A movie full of suspense.","e1t":"Gerilim (heyecanlı bekleyiş) dolu bir film.","e2":"Don't keep me in suspense!","e2t":"Beni merakta bırakma!"},{"w":"suspension","tr":"askıya alma / uzaklaştırma / süspansiyon","te":"Noun","tt":"İsim","de":"The act of stopping something for a period; or part of a car","dt":"Bir şeyi bir süreliğine durdurma eylemi; veya araba parçası","e1":"Suspension of hostilities.","e1t":"Çatışmaların durdurulması.","e2":"Car suspension system.","e2t":"Araba süspansiyon sistemi."},{"w":"suspicion","tr":"şüphe / kuşku / zan","te":"Noun","tt":"İsim","de":"A feeling that someone has done something wrong","dt":"Birinin yanlış bir şey yaptığına dair his","e1":"To be under suspicion.","e1t":"Zan (şüphe) altında olmak.","e2":"A deep suspicion of strangers.","e2t":"Yabancılara karşı derin bir kuşku."},{"w":"suspicious","tr":"şüpheli / kuşkulu","te":"Adjective","tt":"Sıfat","de":"Making you feel that something is wrong or illegal","dt":"Bir şeyin yanlış veya yasadışı olduğunu hissettiren","e1":"Suspicious behavior.","e1t":"Şüpheli davranış.","e2":"He is suspicious of my motives.","e2t":"Benim niyetlerimden şüpheleniyor."},{"w":"sustain","tr":"sürdürmek / devam ettirmek / ayakta tutmak","te":"Verb","tt":"Fiil","de":"To cause something to continue for a long time","dt":"Bir şeyin uzun süre devam etmesini sağlamak","e1":"To sustain economic growth.","e1t":"Ekonomik büyümeyi sürdürmek.","e2":"The earth cannot sustain such a large population.","e2t":"Dünya bu kadar büyük bir nüfusu besleyemez (ayakta tutamaz)."},{"w":"sustainable","tr":"sürdürülebilir","te":"Adjective","tt":"Sıfat","de":"Able to continue over a period of time","dt":"Bir süre boyunca devam edebilen","e1":"Sustainable development.","e1t":"Sürdürülebilir kalkınma.","e2":"Sustainable energy sources.","e2t":"Sürdürülebilir enerji kaynakları."},{"w":"sustenance","tr":"gıda / besin / geçim","te":"Noun","tt":"İsim","de":"Food and drink that keep you alive","dt":"Sizi hayatta tutan yiyecek ve içecek","e1":"To seek sustenance.","e1t":"Gıda (besin) aramak.","e2":"Spiritual sustenance.","e2t":"Manevi gıda (destek)."},{"w":"swallow","tr":"yutmak / kırlangıç / yudum","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move food from your mouth into your stomach","dt":"Yiyeceği ağızdan mideye indirmek","e1":"Swallow the pill with water.","e1t":"Hapı suyla yut.","e2":"To swallow one's pride.","e2t":"Gururunu ayaklar altına almak (yutmak)."},{"w":"swamp","tr":"bataklık / boğulmak (işe vb.) / istila etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An area of very wet soft land; or to overwhelm","dt":"Çok ıslak ve yumuşak arazi; veya birini (işe) boğmak","e1":"To be swamped with work.","e1t":"İşe boğulmak.","e2":"Tropical swamp.","e2t":"Tropikal bataklık."},{"w":"swan","tr":"kuğu / aylak aylak gezmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large white bird with a long neck","dt":"Uzun boyunlu büyük beyaz kuş","e1":"A graceful swan.","e1t":"Zarif bir kuğu.","e2":"To swan around (to move in a relaxed way).","e2t":"Keyifle (aylak aylak) dolaşmak."},{"w":"swarm","tr":"sürü (böcek/arı) / üşüşmek / akın etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large group of insects moving together","dt":"Birlikte hareket eden geniş böcek grubu","e1":"A swarm of bees.","e1t":"Arı sürüsü.","e2":"Tourists swarmed into the city.","e2t":"Turistler şehre akın etti (üşüştü)."},{"w":"sway","tr":"sallanmak / etkilemek / hakimiyet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move slowly from side to side; or to influence","dt":"Yanlara doğru yavaşça sallanmak; veya etkilemek","e1":"The trees swayed in the wind.","e1t":"Ağaçlar rüzgarda sallandı.","e2":"To be easily swayed by public opinion.","e2t":"Kamuoyu görüşünden kolayca etkilenmek."},{"w":"swear","tr":"yemin etmek / küfretmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To promise something formally; or to use rude words","dt":"Resmi olarak söz vermek; veya kaba kelimeler kullanmak","e1":"I swear to tell the truth.","e1t":"Doğruyu söyleyeceğime yemin ederim.","e2":"Stop swearing in front of the children.","e2t":"Çocukların önünde küfretmeyi bırak."},{"w":"sweat","tr":"ter / terlemek / kan ter içinde kalmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The liquid that comes out of your skin when you are hot","dt":"Sıcak olduğunda deriden çıkan sıvı","e1":"To wipe the sweat from your forehead.","e1t":"Alnındaki teri silmek.","e2":"He was sweating with fear.","e2t":"Korkudan terliyordu."},{"w":"sweater","tr":"kazak / süveter","te":"Noun","tt":"İsim","de":"A warm piece of clothing with long sleeves","dt":"Uzun kollu sıcak tutan giysi","e1":"A wool sweater.","e1t":"Yün kazak.","e2":"To wear a sweater.","e2t":"Kazak giymek."},{"w":"sweep","tr":"süpürmek / sürüklemek / geniş alan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To clean a floor using a brush; or to move quickly","dt":"Fırça kullanarak yerleri temizlemek; veya hızla hareket etmek","e1":"To sweep the floor.","e1t":"Yerleri süpürmek.","e2":"The flood swept away the cars.","e2t":"Sel arabaları sürükleyip götürdü."},{"w":"sweeten","tr":"tatlandırmak / şirinleştirmek","te":"Verb","tt":"Fiil","de":"To make something taste sweet; or to make more pleasant","dt":"Bir şeyin tadını tatlı yapmak; veya daha hoş hale getirmek","e1":"To sweeten tea with honey.","e1t":"Çayı balla tatlandırmak.","e2":"To sweeten the deal.","e2t":"Anlaşmayı cazip hale getirmek (şirinleştirmek)."},{"w":"swell","tr":"şişmek / kabarmak / artmak / harika (argo)","te":"Verb/Noun/Adj","tt":"To become larger than normal","de":"Normalden daha büyük hale gelmek","dt":"My ankle started to swell.","e1":"Ayak bileğim şişmeye başladı.","e1t":"A swell of pride.","e2":"Gurur kabarması.","e2t":""},{"w":"swift","tr":"hızlı / süratli / çabuk / ebabil (kuş)","te":"Adjective/Noun/Adv","tt":"Happening or moving very quickly","de":"Çok hızlı gerçekleşen veya hareket eden","dt":"A swift reaction.","e1":"Çabuk (hızlı) bir tepki.","e1t":"Swift progress.","e2":"Hızlı ilerleme.","e2t":""},{"w":"swim","tr":"yüzmek / yüzüş / başı dönmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move through water by moving your body","dt":"Vücudu hareket ettirerek suyun içinde ilerlemek","e1":"To go for a swim.","e1t":"Yüzmeye gitmek.","e2":"My head is swimming (I feel dizzy).","e2t":"Başım dönüyor."},{"w":"swindle","tr":"dolandırmak / sahtekarlık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get money from someone by deceiving them","dt":"Birini aldatarak parasını almak","e1":"He swindled investors out of millions.","e1t":"Yatırımcıları milyonlarca dolar dolandırdı.","e2":"A major tax swindle.","e2t":"Büyük bir vergi dolandırıcılığı."},{"w":"swing","tr":"sallanmak / salıncak / döndürmek / keskin dönüş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move backwards and forwards while hanging","dt":"Asılı haldeyken ileri geri hareket etmek","e1":"The kids are on the swings.","e1t":"Çocuklar salıncakta.","e2":"To swing a bag.","e2t":"Çantayı sallamak."},{"w":"swipe","tr":"kaydırmak (kart/ekran) / sertçe vurmak / çalmak (argo)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move a card through a machine; or to hit","dt":"Kartı makineden geçirmek; veya vurmak","e1":"Swipe your card here.","e1t":"Kartınızı buradan kaydırın.","e2":"To swipe a screen.","e2t":"Ekranı kaydırmak."},{"w":"switch","tr":"anahtar / şalter / değiştirmek / geçiş yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small device that starts or stops electricity","dt":"Elektriği başlatan veya durduran küçük cihaz","e1":"Light switch.","e1t":"Işık anahtarı.","e2":"To switch off the TV.","e2t":"TV'yi kapatmak."},{"w":"sword","tr":"kılıç","te":"Noun","tt":"İsim","de":"A weapon with a long metal blade and a handle","dt":"Uzun metal bıçağı ve sapı olan silah","e1":"To draw a sword.","e1t":"Kılıç çekmek.","e2":"A double","e2t":"edged sword."},{"w":"syllable","tr":"hece","te":"Noun","tt":"İsim","de":"A unit of pronunciation containing one vowel sound","dt":"Bir ünlü ses içeren telaffuz birimi","e1":"\"Apple\" has two syllables.","e1t":"\"Apple\" kelimesi iki hecelidir.","e2":"To stress the first syllable.","e2t":"İlk heceyi vurgulamak."},{"w":"symbol","tr":"sembol / simge","te":"Noun","tt":"İsim","de":"A sign or object that represents an idea","dt":"Bir fikri temsil eden işaret veya nesne","e1":"The dove is a symbol of peace.","e1t":"Güvercin barışın sembolüdür.","e2":"Chemical symbols.","e2t":"Kimyasal semboller."},{"w":"symbolize / symbolise","tr":"sembolize etmek / simgelemek","te":"Verb","tt":"Fiil","de":"To be a symbol of something","dt":"Bir şeyin sembolü olmak","e1":"White symbolizes purity.","e1t":"Beyaz saflığı simgeler.","e2":"What does this logo symbolize?","e2t":"Bu logo neyi sembolize ediyor?"},{"w":"symmetric / symmetrical","tr":"simetrik","te":"Adjective","tt":"Sıfat","de":"Having two halves that are exactly the same","dt":"Birbirinin tamamen aynısı olan iki yarıya sahip olan","e1":"A symmetrical pattern.","e1t":"Simetrik bir desen.","e2":"The human face is not perfectly symmetrical.","e2t":"İnsan yüzü mükemmel bir şekilde simetrik değildir."},{"w":"symmetry","tr":"simetri","te":"Noun","tt":"İsim","de":"The quality of having two halves that match exactly","dt":"Birbirine tam uyan iki yarıya sahip olma niteliği","e1":"The symmetry of the building.","e1t":"Binanın simetrisi.","e2":"Lack of symmetry.","e2t":"Simetri eksikliği."},{"w":"sympathetic","tr":"sempatik / halden anlayan / cana yakın","te":"Adjective","tt":"Sıfat","de":"Showing that you understand and care about someone's problems","dt":"Birinin sorunlarını anladığını ve önemsediğini gösteren","e1":"A sympathetic listener.","e1t":"Halden anlayan (duyarlı) bir dinleyici.","e2":"To be sympathetic toward the strikers.","e2t":"Grevdekilerin durumuna anlayış göstermek."},{"w":"sympathize / sympathise","tr":"halden anlamak / duygularını paylaşmak / acısını paylaşmak","te":"Verb","tt":"Fiil","de":"To understand and care about someone's problems","dt":"Birinin sorunlarını anlamak ve önemsemek","e1":"I sympathize with you, but I can't help.","e1t":"Halinden anlıyorum (duygularını paylaşıyorum) ama yardım edemem.","e2":"To sympathize with a cause.","e2t":"Bir davayı desteklemek (fikren paylaşmak)."},{"w":"sympathy","tr":"sempati / acıma / halden anlama / taziye","te":"Noun","tt":"İsim","de":"A feeling of understanding and caring about someone","dt":"Birini anlama ve önemseme hissi","e1":"To have deep sympathy for the victims.","e1t":"Mağdurlar için derin bir üzüntü (sempati) duymak.","e2":"Letter of sympathy.","e2t":"Taziye mektubu."},{"w":"symphony","tr":"senfoni","te":"Noun","tt":"İsim","de":"A long piece of music for an orchestra","dt":"Orkestra için uzun müzik parçası","e1":"Beethoven's Ninth Symphony.","e1t":"Beethoven'ın 9. Senfonisi.","e2":"Symphony orchestra.","e2t":"Senfoni orkestrası."},{"w":"symposium","tr":"sempozyum / bilgi şöleni","te":"Noun","tt":"İsim","de":"A formal meeting at which experts discuss a subject","dt":"Uzmanların bir konuyu tartıştığı resmi toplantı","e1":"To organize a symposium on cancer research.","e1t":"Kanser araştırmaları üzerine bir sempozyum düzenlemek.","e2":"International symposium.","e2t":"Uluslararası sempozyum."},{"w":"symptom","tr":"semptom / belirti","te":"Noun","tt":"İsim","de":"A physical or mental sign of an illness","dt":"Bir hastalığın fiziksel veya zihinsel belirtisi","e1":"Symptoms of a cold.","e1t":"Soğuk algınlığı belirtileri.","e2":"A symptom of a much deeper problem.","e2t":"Çok daha derin bir sorunun belirtisi."},{"w":"synagogue","tr":"sinagog / havra","te":"Noun","tt":"İsim","de":"A building where Jewish people worship","dt":"Yahudilerin ibadet ettiği bina","e1":"To go to the synagogue.","e1t":"Sinagoga gitmek.","e2":"Ancient synagogue.","e2t":"Antik sinagog."},{"w":"synchronize / synchronise","tr":"senkronize etmek / eşzamanlı hale getirmek","te":"Verb","tt":"Fiil","de":"To cause to happen at the same time","dt":"Aynı anda gerçekleşmesini sağlamak","e1":"Synchronize your watches!","e1t":"Saatlerinizi ayarlayın (senkronize edin)!","e2":"To synchronize data.","e2t":"Verileri eşzamanlı hale getirmek."},{"w":"syndicate","tr":"sendika / konsorsiyum / ortaklık / birlik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of people or companies working together","dt":"Birlikte çalışan insan veya şirket grubu","e1":"A crime syndicate.","e1t":"Suç şebekesi (birliği).","e2":"A lottery syndicate.","e2t":"Piyango ortaklığı."},{"w":"synonym","tr":"eş anlamlı / anlamdaş","te":"Noun","tt":"İsim","de":"A word that has the same meaning as another word","dt":"Başka bir kelimeyle aynı anlama gelen kelime","e1":"\"Shut\" is a synonym of \"close\".","e1t":"\"Shut\", \"close\" kelimesinin eş anlamlısıdır.","e2":"To look for synonyms in a dictionary.","e2t":"Sözlükte eş anlamlı kelimeler aramak."},{"w":"synthesis","tr":"sentez / birleşim","te":"Noun","tt":"İsim","de":"The act of combining different parts to make a whole","dt":"Bir bütün oluşturmak için farklı parçaları birleştirme eylemi","e1":"A synthesis of different artistic styles.","e1t":"Farklı sanatsal tarzların bir sentezi.","e2":"Protein synthesis.","e2t":"Protein sentezi."},{"w":"synthetic","tr":"sentetik / yapay","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Made by people; not natural","dt":"İnsan yapımı; doğal olmayan","e1":"Synthetic fibers like nylon.","e1t":"Naylon gibi sentetik lifler.","e2":"Synthetic drugs.","e2t":"Sentetik ilaçlar."},{"w":"syringe","tr":"şırınga / enjektör","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool used for injecting or removing liquids from the body","dt":"Vücuda sıvı enjekte etmek veya vücuttan sıvı almak için kullanılan alet","e1":"A disposable syringe.","e1t":"Tek kullanımlık şırınga.","e2":"The nurse prepared the syringe.","e2t":"Hemşire şırıngayı hazırladı."},{"w":"syrup","tr":"şurup / ağda","te":"Noun","tt":"İsim","de":"A thick sweet liquid","dt":"Yoğun tatlı sıvı","e1":"Cough syrup.","e1t":"Öksürük şurubu.","e2":"Maple syrup.","e2t":"Akçaağaç şurubu."},{"w":"systematic","tr":"sistematik / düzenli","te":"Adjective","tt":"Sıfat","de":"Done according to a fixed plan or system","dt":"Sabit bir plana veya sisteme göre yapılan","e1":"A systematic approach to the problem.","e1t":"Soruna sistematik bir yaklaşım.","e2":"Systematic errors.","e2t":"Sistematik hatalar."},{"w":"tablecloth","tr":"masa örtüsü","te":"Noun","tt":"İsim","de":"A cloth used for covering a table","dt":"Masayı örtmek için kullanılan kumaş","e1":"To spread a tablecloth.","e1t":"Masa örtüsü sermek.","e2":"A white linen tablecloth.","e2t":"Beyaz keten bir masa örtüsü."},{"w":"tablet","tr":"tablet / hap / levha","te":"Noun","tt":"İsim","de":"A small round solid piece of medicine; or a flat computer","dt":"Küçük yuvarlak katı ilaç parçası; veya düz bilgisayar","e1":"Take two tablets after meals.","e1t":"Yemeklerden sonra iki tablet (hap) alın.","e2":"A graphic tablet.","e2t":"Grafik tablet."},{"w":"taboo","tr":"tabu / yasak","te":"Noun/Adjective/Verb","tt":"Something that people do not do for religious or social reasons","de":"İnsanların dini veya sosyal nedenlerle yapmadığı şey","dt":"Tipping is a taboo in some cultures.","e1":"Bazı kültürlerde bahşiş vermek tabudur.","e1t":"To break a taboo.","e2":"Bir tabuyu yıkmak.","e2t":""},{"w":"tackle","tr":"ele almak / göğüslemek / müdahale etmek (spor) / takım (takım/taklavat)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To try to deal with a difficult problem","dt":"Zor bir sorunla başa çıkmaya çalışmak","e1":"To tackle climate change.","e1t":"İklim değişikliğiyle mücadele etmek (ele almak).","e2":"A football tackle.","e2t":"Futbolda müdahale (top çalma hamlesi)."},{"w":"tact","tr":"nezaket / incelik / nabza göre şerbet verme","te":"Noun","tt":"İsim","de":"The ability to say or do things without offending people","dt":"İnsanları kırmadan bir şeyler söyleme veya yapma yeteneği","e1":"He showed great tact in dealing with the situation.","e1t":"Durumu idare ederken büyük bir nezaket (incelik) gösterdi.","e2":"To lack tact.","e2t":"Patavatsız olmak (incelikten yoksun olmak)."},{"w":"tactful","tr":"nazik / düşünceli / anlayışlı","te":"Adjective","tt":"Sıfat","de":"Careful not to say things that could upset people","dt":"İnsanları üzebilecek şeyleri söylememeye dikkat eden","e1":"A tactful rejection.","e1t":"Nazikçe bir reddediş.","e2":"He was very tactful when he told her the news.","e2t":"Haberi ona verirken çok düşünceli davrandı."},{"w":"tactic","tr":"taktik / yöntem","te":"Noun","tt":"İsim","de":"A planned way of doing something to achieve a goal","dt":"Bir hedefe ulaşmak için planlanmış yol","e1":"Chess tactics.","e1t":"Satranç taktikleri.","e2":"A clever marketing tactic.","e2t":"Zekice bir pazarlama taktiği."},{"w":"tactical","tr":"taktiksel","te":"Adjective","tt":"Sıfat","de":"Relating to the tactics used to achieve a goal","dt":"Bir hedefe ulaşmak için kullanılan taktiklerle ilgili","e1":"A tactical error.","e1t":"Taktiksel bir hata.","e2":"Tactical advantage.","e2t":"Taktiksel avantaj."},{"w":"tag","tr":"etiket / lakap / eklenti / etiketlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of paper or plastic attached to something","dt":"Bir şeye iliştirilen küçük kağıt veya plastik parçası","e1":"Price tag.","e1t":"Fiyat etiketi.","e2":"Name tag.","e2t":"İsimlik (yaka kartı)."},{"w":"tailor","tr":"terzi / uydurmak / şekillendirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person whose job is making clothes; or to adapt","dt":"İşi kıyafet dikmek olan kişi; veya uyarlamak","e1":"To go to the tailor.","e1t":"Terziye gitmek.","e2":"The course is tailored to your needs.","e2t":"Kurs sizin ihtiyaçlarınıza göre uyarlandı."},{"w":"taint","tr":"lekelemek / bozmak / kusur","te":"Verb/Noun","tt":"Fiil/İsim","de":"To spoil something or make it dirty","dt":"Bir şeyi bozmak veya kirletmek","e1":"The water was tainted with chemicals.","e1t":"Su kimyasallarla kirlenmişti.","e2":"To taint a reputation.","e2t":"Bir itibarı lekelemek."},{"w":"take","tr":"off","te":"havalanma / kalkış / taklit (komik)","tt":"Noun","de":"İsim","dt":"The moment when a plane leaves the ground","e1":"Uçağın yerden ayrıldığı an","e1t":"Fasten your seatbelts for take","e2":"off.","e2t":"Kalkış için emniyet kemerlerinizi bağlayın."},{"w":"tale","tr":"masal / hikaye / rivayet","te":"Noun","tt":"İsim","de":"A story, especially one that is invented","dt":"Hikaye, özellikle uydurulmuş olanı","e1":"Fairy tales.","e1t":"Peri masalları.","e2":"A tall tale (an exaggerated story).","e2t":"Abartılı bir hikaye (palavra)."},{"w":"talent","tr":"yetenek / kabiliyet","te":"Noun","tt":"İsim","de":"A natural ability to do something well","dt":"Bir şeyi iyi yapma konusundaki doğal yetenek","e1":"A talent for music.","e1t":"Müzik yeteneği.","e2":"Hidden talent.","e2t":"Gizli yetenek."},{"w":"tally","tr":"çetele / hesap / uyuşmak / saymak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A record of an amount; or to match","dt":"Bir miktarın kaydı; veya eşleşmek/uyuşmak","e1":"To keep a tally of the score.","e1t":"Skorun çetelesini tutmak.","e2":"Your story doesn't tally with the facts.","e2t":"Hikayen gerçeklerle uyuşmuyor."},{"w":"tame","tr":"evcil / ehlileştirmek / uysallaştırmak / sıkıcı","te":"Adjective/Verb","tt":"(Of an animal) not wild or afraid of people","de":"(Hayvan için) vahşi olmayan veya insandan korkmayan","dt":"A tame rabbit.","e1":"Evcil bir tavşan.","e1t":"To tame a wild horse.","e2":"Vahşi bir atı ehlileştirmek.","e2t":""},{"w":"tan","tr":"bronzlaşmak / ten rengi / tabaklamak (deri)","te":"Verb/Noun/Adj","tt":"To become brown from the sun","de":"Güneşten kahverengiye dönmek","dt":"To get a tan.","e1":"Bronzlaşmak.","e1t":"Suntan lotion.","e2":"Güneş yağı (losyonu).","e2t":""},{"w":"tangible","tr":"somut / elle tutulur","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Real and able to be touched or experienced","dt":"Gerçek ve dokunulabilen veya deneyimlenebilen","e1":"Tangible benefits.","e1t":"Somut faydalar.","e2":"Tangible evidence.","e2t":"Elle tutulur (somut) kanıt."},{"w":"tangle","tr":"karıştırmak / arapsaçına dönmek / düğüm","te":"Noun/Verb","tt":"İsim/Fiil","de":"A confused mass of things tied together","dt":"Birbirine karışmış şeyler yığını","e1":"My hair is in a tangle.","e1t":"Saçlarım karışmış (düğüm düğüm).","e2":"To get tangled up in a problem.","e2t":"Bir soruna saplanıp kalmak (karışmak)."},{"w":"tank","tr":"tank / depo / akvaryum","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large container for liquid or gas; or a military vehicle","dt":"Sıvı veya gaz için büyük kap; veya askeri araç","e1":"Fuel tank.","e1t":"Yakıt deposu.","e2":"Fish tank.","e2t":"Akvaryum."},{"w":"tanker","tr":"tanker (gemi/kamyon)","te":"Noun","tt":"İsim","de":"A large ship or truck used for carrying oil or gas","dt":"Petrol veya gaz taşımak için kullanılan büyük gemi veya kamyon","e1":"An oil tanker.","e1t":"Petrol tankeri.","e2":"Water tanker.","e2t":"Su tankeri (arazöz)."},{"w":"tantrum","tr":"öfke nöbeti / huysuzluk","te":"Noun","tt":"İsim","de":"A sudden period of uncontrolled anger, especially in a child","dt":"Özellikle bir çocukta görülen ani kontrolsüz öfke dönemi","e1":"To throw a tantrum.","e1t":"Öfke nöbeti geçirmek (huysuzluk etmek).","e2":"Temper tantrum.","e2t":"Sinir krizi (nöbeti)."},{"w":"tape","tr":"bant / şerit / kaset / kaydetmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long narrow strip of sticky paper or plastic","dt":"Uzun dar yapışkan kağıt veya plastik şerit","e1":"Adhesive tape.","e1t":"Yapışkan bant.","e2":"Measuring tape.","e2t":"Mezura (şerit metre)."},{"w":"taper","tr":"incelmek / giderek azalmak / mum (ince)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become gradually narrower at one end","dt":"Bir uçta giderek daralmak","e1":"The leaves taper to a point.","e1t":"Yapraklar bir noktada incelir.","e2":"To taper off (to decrease gradually).","e2t":"Giderek azalmak (hızı kesilmek)."},{"w":"tapestry","tr":"goblen / duvar halısı / işleme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thick piece of cloth with a picture woven into it","dt":"Üzerine resim dokunmuş kalın kumaş parçası","e1":"A medieval tapestry.","e1t":"Ortaçağ duvar halısı.","e2":"The rich tapestry of life (metaphor).","e2t":"Hayatın zengin mozaiği (dokusu)."},{"w":"target","tr":"hedef / gaye / nişan / hedeflemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that you try to hit; or a goal","dt":"Vurmaya çalıştığınız şey; veya amaç","e1":"To hit the target.","e1t":"Hedefi vurmak.","e2":"Sales target.","e2t":"Satış hedefi."},{"w":"tariff","tr":"tarife / gümrük vergisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tax on goods coming into a country","dt":"Bir ülkeye giren mallar üzerindeki vergi","e1":"To impose tariffs on imports.","e1t":"İthalata gümrük vergisi koymak.","e2":"High tariffs.","e2t":"Yüksek tarifeler (vergiler)."},{"w":"tarnish","tr":"kararmak / lekelemek / matlaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a metal lose its shine; or to spoil a reputation","dt":"Metalin parlaklığını kaybetmesini sağlamak; veya bir itibarı bozmak","e1":"Silver tarnishes easily.","e1t":"Gümüş kolayca kararır.","e2":"To tarnish a reputation.","e2t":"İtibarı lekelemek."},{"w":"tart","tr":"tart / ekşi / keskin (cevap) / yosma (argo)","te":"Noun/Adj/Verb","tt":"An open pie with fruit; or having a sharp sour taste","de":"Meyveli açık turta; veya keskin ekşi tat","dt":"Apple tart.","e1":"Elmalı tart.","e1t":"A tart reply.","e2":"Keskin (iğneleyici) bir cevap.","e2t":""},{"w":"task","tr":"görev / iş / ödev","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of work that needs to be done","dt":"Yapılması gereken iş","e1":"To perform a task.","e1t":"Bir görevi yerine getirmek.","e2":"A difficult task.","e2t":"Zor bir iş."},{"w":"tassel","tr":"püskül / püskül takmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of threads tied together at one end for decoration","dt":"Süsleme için bir ucu bağlanmış iplik grubu","e1":"Curtains with gold tassels.","e1t":"Altın püsküllü perdeler.","e2":"Graduation tassel.","e2t":"Mezuniyet kepi püskülü."},{"w":"taste","tr":"tat / tatmak / zevk / beğeni","te":"Noun/Verb","tt":"İsim/Fiil","de":"The flavor of something; or the ability to judge art","dt":"Bir şeyin lezzeti; veya sanatı yargılama yeteneği","e1":"To have a taste of the soup.","e1t":"Çorbanın tadına bakmak.","e2":"Everyone has different tastes.","e2t":"Herkesin zevki farklıdır."},{"w":"taunt","tr":"alay etmek / laf atmak / kışkırtmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To intentionally upset someone by mocking them","dt":"Birini onunla alay ederek kasten üzmek","e1":"The kids taunted him about his weight.","e1t":"Çocuklar kilosuyla ilgili onunla alay etti.","e2":"Cruel taunts.","e2t":"Zalimce alaylar (laf atmalar)."},{"w":"taut","tr":"gergin / gerili / düzgün","te":"Adjective","tt":"Sıfat","de":"Stretched tightly; or showing control","dt":"Sıkıca gerilmiş; veya kontrol gösteren","e1":"A taut rope.","e1t":"Gergin bir ip.","e2":"Taut muscles.","e2t":"Gergin kaslar."},{"w":"tavern","tr":"taverna / meyhane / han","te":"Noun","tt":"İsim","de":"A place where alcohol is sold and people can stay","dt":"Alkol satılan ve insanların konaklayabildiği yer","e1":"A country tavern.","e1t":"Bir köy meyhanesi (hanı).","e2":"To spend the evening in a tavern.","e2t":"Akşamı bir meyhanede geçirmek."},{"w":"tax","tr":"vergi / vergilendirmek / yormak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money paid to the government","dt":"Hükümete ödenen para","e1":"Income tax.","e1t":"Gelir vergisi.","e2":"To tax cigarettes.","e2t":"Sigarayı vergilendirmek."},{"w":"taxation","tr":"vergilendirme","te":"Noun","tt":"İsim","de":"The system of taxing people and organizations","dt":"İnsanları ve kuruluşları vergilendirme sistemi","e1":"To reduce the level of taxation.","e1t":"Vergilendirme seviyesini düşürmek.","e2":"Direct taxation.","e2t":"Doğrudan vergilendirme."},{"w":"tease","tr":"şakalaşmak / takılmak / kızdırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh at someone in a friendly or unkind way","dt":"Birine dostça veya kaba bir şekilde gülmek (takılmak)","e1":"Don't tease your little sister.","e1t":"Küçük kız kardeşinle uğraşma (ona takılma).","e2":"He is such a tease.","e2t":"O çok şakacıdır (insanlarla uğraşmayı sever)."},{"w":"technical","tr":"teknik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to practical skills and methods","dt":"Pratik beceriler ve yöntemlerle ilgili","e1":"Technical problems.","e1t":"Teknik sorunlar.","e2":"A technical error.","e2t":"Teknik bir hata."},{"w":"technician","tr":"teknisyen / teknik eleman","te":"Noun","tt":"İsim","de":"A person whose job is to look after equipment","dt":"İşi ekipmanlarla ilgilenmek olan kişi","e1":"Laboratory technician.","e1t":"Laboratuvar teknisyeni.","e2":"Computer technician.","e2t":"Bilgisayar teknisyeni."},{"w":"technique","tr":"teknik / yöntem / usul","te":"Noun","tt":"İsim","de":"A particular way of doing something","dt":"Bir şeyi yapmanın belirli bir yolu","e1":"Modern farming techniques.","e1t":"Modern tarım teknikleri.","e2":"To master a technique.","e2t":"Bir teknik üzerinde uzmanlaşmak."},{"w":"technology","tr":"teknoloji","te":"Noun","tt":"İsim","de":"Scientific knowledge used for practical purposes","dt":"Pratik amaçlar için kullanılan bilimsel bilgi","e1":"Information technology (IT).","e1t":"Bilgi teknolojisi.","e2":"Modern technology.","e2t":"Modern teknoloji."},{"w":"tedious","tr":"sıkıcı / bıktırıcı / yavaş ve yorucu","te":"Adjective","tt":"Sıfat","de":"Boring and lasting for a long time","dt":"Sıkıcı ve uzun süren","e1":"A tedious job.","e1t":"Bıktırıcı (sıkıcı) bir iş.","e2":"The journey was long and tedious.","e2t":"Yolculuk uzun ve yorucuydu."},{"w":"teem","tr":"dolu olmak / bol olmak / bardaktan boşalırcasına yağmak","te":"Verb","tt":"Fiil","de":"To contain a large number of something","dt":"Bir şeyden çok sayıda barındırmak","e1":"The river is teeming with fish.","e1t":"Nehir balık kaynıyor (balık dolu).","e2":"It’s teeming with rain.","e2t":"Bardaktan boşalırcasına yağmur yağıyor."},{"w":"televise","tr":"televizyonda yayınlamak","te":"Verb","tt":"Fiil","de":"To broadcast something on television","dt":"Bir şeyi televizyonda yayınlamak","e1":"The match will be televised live.","e1t":"Maç televizyondan canlı yayınlanacak.","e2":"A televised debate.","e2t":"Televizyonda yayınlanan bir tartışma."},{"w":"temper","tr":"öfke / huy / sinir / yumuşatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The tendency to become angry; or to make something less severe","dt":"Öfkelenme eğilimi; veya bir şeyi daha az şiddetli hale getirmek","e1":"To lose your temper.","e1t":"Öfkelenmek (sinirlerine hakim olamamak).","e2":"A violent temper.","e2t":"Sert bir mizaç (huy)."},{"w":"temperament","tr":"mizaç / yaradılış / huy","te":"Noun","tt":"İsim","de":"A person's distinct nature or character","dt":"Bir kişinin kendine has doğası veya karakteri","e1":"An artistic temperament.","e1t":"Sanatçı mizacı.","e2":"He has a very nervous temperament.","e2t":"Çok gergin bir yaradılışı (huyu) var."},{"w":"temperate","tr":"ılıman / ölçülü / aşırıya kaçmayan","te":"Adjective","tt":"Sıfat","de":"(Of weather) not extreme; or showing self","dt":"control","e1":"(Hava için) aşırı olmayan; veya otokontrol gösteren","e1t":"A temperate climate.","e2":"Ilıman bir iklim.","e2t":"To lead a temperate life."},{"w":"temperature","tr":"sıcaklık / ateş (vücut)","te":"Noun","tt":"İsim","de":"How hot or cold something is; or the heat of a body","dt":"Bir şeyin ne kadar sıcak veya soğuk olduğu; veya vücut ısısı","e1":"To take someone's temperature.","e1t":"Birinin ateşini ölçmek.","e2":"Room temperature.","e2t":"Oda sıcaklığı."},{"w":"tempest","tr":"fırtına / kasırga","te":"Noun","tt":"İsim","de":"A violent windy storm (literary)","dt":"Şiddetli rüzgarlı fırtına (edebi)","e1":"A tempest at sea.","e1t":"Denizde bir fırtına.","e2":"A tempest in a teapot (a lot of fuss about something small).","e2t":"Bir kaşık suda fırtına koparmak."},{"w":"tempo","tr":"tempo / hız / ritim","te":"Noun","tt":"İsim","de":"The speed at which an activity happens or music is played","dt":"Bir faaliyetin hızı veya müziğin çalınma hızı","e1":"To increase the tempo of the game.","e1t":"Oyunun temposunu artırmak.","e2":"A slow musical tempo.","e2t":"Yavaş bir müzik temposu."},{"w":"temporary","tr":"geçici","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Lasting for only a short time","dt":"Sadece kısa bir süre için süren","e1":"A temporary job.","e1t":"Geçici bir iş.","e2":"Temporary accommodation.","e2t":"Geçici konaklama."},{"w":"tempt","tr":"cezbetmek / baştan çıkarmak / özendirmek","te":"Verb","tt":"Fiil","de":"To make someone want to have or do something (especially something wrong)","dt":"Birinin bir şeyi yapmasını veya sahip olmasını istemesini sağlamak (özellikle yanlış bir şeyi)","e1":"The offer tempted him to stay.","e1t":"Teklif onu kalmaya cezbetti.","e2":"To be tempted by chocolate.","e2t":"Çikolata tarafından baştan çıkarılmak (canı çekmek)."},{"w":"temptation","tr":"cazibe / baştan çıkma / şeytana uyma","te":"Noun","tt":"İsim","de":"A feeling that you want to do something, even if you know it is wrong","dt":"Yanlış olduğunu bilsen de bir şeyi yapma isteği","e1":"To resist temptation.","e1t":"Günaha (cazibeye) karşı koymak.","e2":"The temptation of easy money.","e2t":"Kolay paranın cazibesi."},{"w":"tenancy","tr":"kiracılık / kira süresi","te":"Noun","tt":"Isim","de":"The right to live in a building or use land for a period","dt":"Bir binada yaşama veya araziyi kullanma hakkı (süresi)","e1":"A six","e1t":"month tenancy.","e2":"Altı aylık kiracılık (kira süresi).","e2t":"Tenancy agreement."},{"w":"tenant","tr":"kiracı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who pays rent for the use of land or a building","dt":"Arazi veya bina kullanımı için kira ödeyen kişi","e1":"The desk was left by the previous tenant.","e1t":"Masa önceki kiracı tarafından bırakılmıştı.","e2":"Evicting a tenant.","e2t":"Kiracıyı tahliye etmek."},{"w":"tend","tr":"eğiliminde olmak / bakmak / ilgilenmek","te":"Verb","tt":"Fiil","de":"To be likely to happen or behave in a way; or to look after","dt":"Bir şekilde gerçekleşme veya davranma olasılığı olmak; veya bakmak","e1":"Prices tend to rise in summer.","e1t":"Fiyatlar yazın yükselme eğilimindedir.","e2":"To tend a garden.","e2t":"Bahçeyle ilgilenmek (bakmak)."},{"w":"tendency","tr":"eğilim / meyil / trend","te":"Noun","tt":"İsim","de":"A likelihood that someone will behave in a particular way","dt":"Birinin belirli bir şekilde davranma olasılığı","e1":"A tendency toward violence.","e1t":"Şiddete meyillilik.","e2":"Market tendencies.","e2t":"Piyasa eğilimleri."},{"w":"tender","tr":"şefkatli / yumuşak (et vb.) / hassas / teklif / ihale","te":"Adjective/Noun/Verb","tt":"Kind and loving; or easy to cut; or an official offer","de":"Nazik ve sevgi dolu; veya kolay kesilen; veya resmi teklif","dt":"A tender kiss.","e1":"Şefkatli bir öpücük.","e1t":"Tender meat.","e2":"Yumuşak et.","e2t":""},{"w":"tenement","tr":"kiralık konut / büyük ucuz apartman","te":"Noun","tt":"İsim","de":"A large building divided into apartments, especially in a poor area","dt":"Özellikle fakir bir bölgede dairelere bölünmüş büyük bina","e1":"To live in a crowded tenement.","e1t":"Kalabalık bir kiralık konutta yaşamak.","e2":"Tenement block.","e2t":"Apartman bloğu."},{"w":"tense","tr":"gergin / zaman (dilbilgisi) / gerilmek","te":"Adjective/Noun/Verb","tt":"Nervous and not relaxed; or a form of a verb","de":"Gergin ve rahatlamamış; veya fiil zamanı","dt":"He looked very tense.","e1":"Çok gergin görünüyordu.","e1t":"Present tense.","e2":"Şimdiki zaman.","e2t":""},{"w":"tension","tr":"gerilim / gerginlik / tansiyon","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of nervousness or lack of trust; or the state of being tight","dt":"Sinirlilik veya güvensizlik hissi; veya gergin olma durumu","e1":"Political tension.","e1t":"Siyasi gerginlik.","e2":"To reduce the tension.","e2t":"Gerginliği azaltmak."},{"w":"tentacle","tr":"dokunaç / kol (ahtapot vb.)","te":"Noun","tt":"İsim","de":"A long, thin part of some sea creatures used for feeling or moving","dt":"Bazı deniz canlılarının hissetmek veya hareket etmek için kullandığı uzun ince parça","e1":"The octopus has eight tentacles.","e1t":"Ahtapotun sekiz dokunacı (kolu) vardır.","e2":"The tentacles of a large corporation.","e2t":"Büyük bir şirketin kolları (uzantıları)."},{"w":"tentative","tr":"kesin olmayan / tereddütlü / geçici","te":"Adjective","tt":"Sıfat","de":"Not certain or fixed; or done without confidence","dt":"Kesin veya sabit olmayan; veya güven duymadan yapılan","e1":"A tentative plan.","e1t":"Kesinleşmemiş (geçici) bir plan.","e2":"A tentative smile.","e2t":"Tereddütlü bir gülümseme."},{"w":"tenure","tr":"görev süresi / kadro (akademik) / mülkiyet","te":"Noun/Verb","tt":"İsim/Fiil","de":"The period of time an important job is held; or a permanent job","dt":"Önemli bir işin tutulduğu süre; veya kalıcı iş (kadro)","e1":"During his tenure as principal.","e1t":"Müdürlük yaptığı dönem (süresi) boyunca.","e2":"To get tenure at a university.","e2t":"Üniversitede kadro (kalıcılık) almak."},{"w":"term","tr":"terim / dönem / şart / adlandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A word used in a specific subject; or a period of time; or a condition","dt":"Belirli bir konuda kullanılan kelime; veya süre; veya şart","e1":"Technical terms.","e1t":"Teknik terimler.","e2":"School term.","e2t":"Okul dönemi."},{"w":"terminal","tr":"terminal / uç / son / ölümcül","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A building at an airport; or a computer point; or causing death","dt":"Havaalanındaki bina; veya bilgisayar noktası; veya ölüme neden olan","e1":"Airport terminal.","e1t":"Havaalanı terminali.","e2":"Terminal cancer.","e2t":"Ölümcül (son evre) kanser."},{"w":"terminate","tr":"sonlandırmak / bitirmek / (durak) son bulmak","te":"Verb","tt":"Fiil","de":"To bring something to an end","dt":"Bir şeyi sona erdirmek","e1":"To terminate a contract.","e1t":"Bir sözleşmeyi feshetmek (sonlandırmak).","e2":"The train terminates at London.","e2t":"Tren Londra'da seferini bitirir."},{"w":"terminology","tr":"terminoloji / terimler bilgisi","te":"Noun","tt":"İsim","de":"The special words used in a particular subject","dt":"Belirli bir konuda kullanılan özel kelimeler","e1":"Medical terminology.","e1t":"Tıbbi terminoloji.","e2":"To master the terminology.","e2t":"Terminolojiye hakim olmak."},{"w":"terrace","tr":"teras / taraça / bitişik evler dizisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat area outside a house; or a row of similar houses","dt":"Evin dışındaki düz alan; veya benzer evler dizisi","e1":"To have dinner on the terrace.","e1t":"Terasta akşam yemeği yemek.","e2":"A terrace house.","e2t":"Bitişik nizam ev."},{"w":"terrain","tr":"arazi / yer şekilleri","te":"Noun","tt":"İsim","de":"A particular type of land","dt":"Belirli bir arazi türü","e1":"Difficult terrain.","e1t":"Zorlu arazi.","e2":"Mountainous terrain.","e2t":"Dağlık arazi."},{"w":"terrestrial","tr":"yeryüzüne ait / karasal / dünyevi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the Earth or to land rather than water or air","dt":"Su veya havadan ziyade Dünya veya kara ile ilgili","e1":"Terrestrial animals.","e1t":"Kara hayvanları.","e2":"Terrestrial television (non","e2t":"satellite)."},{"w":"terrible","tr":"korkunç / berbat / çok kötü","te":"Adjective","tt":"Sıfat","de":"Very bad or unpleasant","dt":"Çok kötü veya nahoş","e1":"A terrible accident.","e1t":"Korkunç bir kaza.","e2":"I feel terrible.","e2t":"Berbat hissediyorum."},{"w":"terrific","tr":"müthiş / harika / çok büyük","te":"Adjective","tt":"Sıfat","de":"Very good or enjoyable; or very large","dt":"Çok iyi veya keyifli; veya çok büyük","e1":"A terrific idea!","e1t":"Müthiş bir fikir!","e2":"You look terrific.","e2t":"Harika görünüyorsun."},{"w":"terrify","tr":"korkutmak / dehşete düşürmek","te":"Verb","tt":"Fiil","de":"To make someone feel very frightened","dt":"Birini çok korkutmak","e1":"Heights terrify me.","e1t":"Yükseklik beni dehşete düşürüyor.","e2":"A terrifying experience.","e2t":"Korkunç bir deneyim."},{"w":"territory","tr":"bölge / toprak / alan","te":"Noun","tt":"İsim","de":"An area of land that belongs to a country or person","dt":"Bir ülkeye veya kişiye ait arazi alanı","e1":"Occupied territory.","e1t":"İşgal edilmiş topraklar.","e2":"To defend one's territory.","e2t":"Kendi bölgesini savunmak."},{"w":"terror","tr":"terör / dehşet / korku","te":"Noun","tt":"İsim","de":"Great fear; or the use of violence for political goals","dt":"Büyük korku; veya siyasi amaçlar için şiddet kullanımı","e1":"To scream in terror.","e1t":"Dehşet içinde bağırmak.","e2":"The War on Terror.","e2t":"Terörle mücadele."},{"w":"terrorism","tr":"terörizm / terör","te":"Noun","tt":"İsim","de":"The use of violence for political purposes","dt":"Siyasi amaçlar için şiddet kullanımı","e1":"To fight against terrorism.","e1t":"Terörizmle mücadele etmek.","e2":"Act of terrorism.","e2t":"Terör eylemi."},{"w":"terrorist","tr":"terörist","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who uses violence for political purposes","dt":"Siyasi amaçlar için şiddet kullanan kişi","e1":"Terrorist attack.","e1t":"Terörist saldırısı.","e2":"A suspected terrorist.","e2t":"Terörist şüphelisi."},{"w":"testify","tr":"tanıklık etmek / ifade vermek","te":"Verb","tt":"Fiil","de":"To give evidence as a witness in a court","dt":"Mahkemede tanık olarak ifade (kanıt) vermek","e1":"He agreed to testify against his former boss.","e1t":"Eski patronuna karşı tanıklık etmeyi kabul etti.","e2":"To testify under oath.","e2t":"Yeminli ifade vermek."},{"w":"testimonial","tr":"referans (mektubu) / tanıklık / şükran belgesi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A statement about someone's character or qualities","dt":"Birinin karakteri veya nitelikleri hakkında ifade","e1":"To provide a testimonial for a student.","e1t":"Bir öğrenci için referans yazmak.","e2":"Customer testimonials (reviews).","e2t":"Müşteri yorumları (referansları)."},{"w":"testimony","tr":"ifade / tanıklık / kanıt","te":"Noun","tt":"İsim","de":"A formal statement made in a court; or clear proof","dt":"Mahkemede yapılan resmi beyan; veya açık kanıt","e1":"According to the witness's testimony.","e1t":"Tanığın ifadesine göre.","e2":"A testimony to his hard work.","e2t":"Onun sıkı çalışmasının bir kanıtı."},{"w":"textile","tr":"tekstil / dokuma","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A cloth made by hand or machine","dt":"El veya makine ile yapılan kumaş","e1":"The textile industry.","e1t":"Tekstil endüstrisi.","e2":"Cotton textiles.","e2t":"Pamuklu dokumalar."},{"w":"texture","tr":"doku / yapı","te":"Noun/Verb","tt":"İsim/Fiil","de":"The way that something feels when you touch it","dt":"Dokunduğunuzda bir şeyin hissettirme şekli","e1":"A smooth texture.","e1t":"Pürüzsüz bir doku.","e2":"The texture of the soil.","e2t":"Toprağın yapısı (dokusu)."},{"w":"thanksgiving","tr":"şükran / şükretme / şükran günü","te":"Noun","tt":"İsim","de":"An expression of thanks to God; or a US holiday","dt":"Tanrıya teşekkür ifadesi; veya bir ABD bayramı","e1":"A service of thanksgiving.","e1t":"Şükran ayini.","e2":"Thanksgiving Day (celebrated in November).","e2t":"Şükran Günü."},{"w":"thaw","tr":"erimek (buz) / çözülmek / yumuşamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To start to melt; or to become friendlier","dt":"Erimeye başlamak; veya daha dostça davranmak","e1":"The snow is starting to thaw.","e1t":"Kar erimeye başlıyor.","e2":"A thaw in relations.","e2t":"İlişkilerde yumuşama (buzların erimesi)."},{"w":"theatrical","tr":"tiyatro ile ilgili / yapmacık / sahneye özgü","te":"Adjective","tt":"Sıfat","de":"Relating to the theater; or behaving in an exaggerated way","dt":"Tiyatro ile ilgili; veya abartılı davranan","e1":"A theatrical performance.","e1t":"Tiyatral performans.","e2":"He has a very theatrical manner.","e2t":"Çok yapmacık (tiyatral) bir tavrı var."},{"w":"theft","tr":"hırsızlık","te":"Noun","tt":"İsim","de":"The crime of stealing something","dt":"Bir şeyi çalma suçu","e1":"Identity theft.","e1t":"Kimlik hırsızlığı.","e2":"Petty theft.","e2t":"Küçük çaplı hırsızlık."},{"w":"theme","tr":"tema / ana fikir / konu / müzikal motif","te":"Noun/Verb","tt":"İsim/Fiil","de":"The main subject of a talk, book, or movie","dt":"Bir konuşmanın, kitabın veya filmin ana konusu","e1":"The theme of the conference is education.","e1t":"Konferansın teması eğitimdir.","e2":"Theme park.","e2t":"Tema parkı (eğlence parkı)."},{"w":"theology","tr":"teoloji / ilahiyat","te":"Noun","tt":"İsim","de":"The study of religion and religious beliefs","dt":"Din ve dini inançların incelenmesi","e1":"A professor of theology.","e1t":"İlahiyat profesörü.","e2":"Systematic theology.","e2t":"Sistematik teoloji."},{"w":"theoretical","tr":"teorik / kuramsal","te":"Adjective","tt":"Sıfat","de":"Based on ideas or principles, not on practical experience","dt":"Pratik deneyime değil, fikirlere veya ilkelere dayalı","e1":"Theoretical physics.","e1t":"Teorik fizik.","e2":"On a theoretical level.","e2t":"Teorik düzeyde."},{"w":"theory","tr":"teori / kuram / varsayım","te":"Noun","tt":"İsim","de":"An idea or set of ideas used to explain something","dt":"Bir şeyi açıklamak için kullanılan fikir veya fikirler bütünü","e1":"Darwin's theory of evolution.","e1t":"Darwin'in evrim teorisi.","e2":"In theory, it should work.","e2t":"Teorik olarak (kağıt üzerinde) çalışması gerekir."},{"w":"therapeutic","tr":"terapötik / tedavi edici / rahatlatıcı","te":"Adjective","tt":"Sıfat","de":"Helping to cure an illness or make you feel relaxed","dt":"Bir hastalığı iyileştirmeye veya rahatlamanıza yardımcı olan","e1":"I find gardening very therapeutic.","e1t":"Bahçe işlerini çok rahatlatıcı buluyorum.","e2":"Therapeutic massage.","e2t":"Tedavi edici masaj."},{"w":"therapist","tr":"terapist / tedavi uzmanı","te":"Noun","tt":"İsim","de":"A person whose job is to treat a particular type of illness","dt":"İşi belirli bir hastalık türünü tedavi etmek olan kişi","e1":"Speech therapist.","e1t":"Konuşma terapisti.","e2":"Physical therapist.","e2t":"Fizyoterapist."},{"w":"thereafter","tr":"ondan sonra / o zamandan sonra","te":"Adverb","tt":"Zarf","de":"Continuing from that time on","dt":"O zamandan itibaren devam ederek","e1":"He left the company in 2020 and died shortly thereafter.","e1t":"2020'de şirketten ayrıldı ve kısa bir süre sonra (ondan sonra) öldü.","e2":"Thereafter, everything changed.","e2t":"Ondan sonra her şey değişti."},{"w":"thereby","tr":"böylece / bu nedenle / dolayısıyla","te":"Adverb","tt":"Zarf","de":"As a result of this action","dt":"Bu eylemin sonucu olarak","e1":"He signed the contract, thereby agreeing to the terms.","e1t":"Sözleşmeyi imzaladı, böylece şartları kabul etmiş oldu.","e2":"Our costs will fall, thereby increasing profits.","e2t":"Maliyetlerimiz düşecek, dolayısıyla kârımız artacak."},{"w":"thermal","tr":"termal / ısı / ısıl","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to heat","dt":"Isı ile ilgili","e1":"Thermal energy.","e1t":"Isı enerjisi.","e2":"Thermal underwear.","e2t":"Termal iç çamaşırı."},{"w":"thermometer","tr":"termometre / derece","te":"Noun","tt":"İsim","de":"A device used for measuring temperature","dt":"Sıcaklığı ölçmek için kullanılan cihaz","e1":"The thermometer showed 30 degrees.","e1t":"Termometre 30 dereceyi gösteriyordu.","e2":"Clinical thermometer.","e2t":"Ateş ölçer (klinik termometre)."},{"w":"thesis","tr":"tez / iddia / kuram","te":"Noun","tt":"İsim","de":"A long piece of writing done for a university degree","dt":"Üniversite derecesi için yapılan uzun yazılı çalışma (tez)","e1":"He is writing his PhD thesis on AI.","e1t":"Yapay zeka üzerine doktora tezini yazıyor.","e2":"The main thesis of the book.","e2t":"Kitabın ana iddiası (tezi)."},{"w":"thicket","tr":"çalılık / sık ağaçlık","te":"Noun","tt":"İsim","de":"A group of trees or bushes growing close together","dt":"Birbirine yakın büyüyen ağaç veya çalı grubu","e1":"A thicket of bamboo.","e1t":"Bambu çalılığı.","e2":"To hide in a dense thicket.","e2t":"Yoğun bir çalılıkta saklanmak."},{"w":"thigh","tr":"uyluk / kalça","te":"Noun","tt":"İsim","de":"The top part of the leg above the knee","dt":"Bacağın diz üstündeki üst kısmı","e1":"He strained a muscle in his thigh.","e1t":"Uyluğundaki bir kası incitti.","e2":"Thigh bone (femur).","e2t":"Uyluk kemiği."},{"w":"thimble","tr":"yüksük","te":"Noun","tt":"İsim","de":"A small metal or plastic cap used to protect the finger during sewing","dt":"Dikiş dikerken parmağı korumak için kullanılan küçük başlık","e1":"A silver thimble.","e1t":"Gümüş bir yüksük.","e2":"Only a thimbleful of water (very small amount).","e2t":"Sadece bir yüksük dolusu su."},{"w":"thirsty","tr":"susamış / arzulu","te":"Adjective","tt":"Sıfat","de":"Needing to drink; or having a strong desire","dt":"İçmeye ihtiyaç duyan; veya güçlü bir arzusu olan","e1":"I’m very thirsty.","e1t":"Çok susadım.","e2":"Power","e2t":"thirsty (greedy for power)."},{"w":"thorny","tr":"dikenli / çetin / sıkıntılı","te":"Adjective","tt":"Sıfat","de":"Covered with thorns; or difficult to deal with","dt":"Dikenlerle kaplı; veya başa çıkması zor","e1":"A thorny bush.","e1t":"Dikenli bir çalı.","e2":"A thorny problem (a difficult issue).","e2t":"Çetin (çetrefilli) bir sorun."},{"w":"thorough","tr":"titiz / kapsamlı / tam","te":"Adjective","tt":"Sıfat","de":"Careful and detailed; or complete","dt":"Dikkatli ve detaylı; veya tam/eksiksiz","e1":"A thorough investigation.","e1t":"Kapsamlı (titiz) bir soruşturma.","e2":"He is very thorough in his work.","e2t":"İşinde çok titizdir."},{"w":"thoroughfare","tr":"ana yol / işlek cadde / geçit","te":"Noun","tt":"İsim","de":"A main road through a place","dt":"Bir yerin içinden geçen ana yol","e1":"No thoroughfare (closed to traffic).","e1t":"Geçiş yoktur (yol kapalı).","e2":"A busy thoroughfare.","e2t":"İşlek bir ana yol."},{"w":"thoughtful","tr":"düşünceli / nazik / dalgın","te":"Adjective","tt":"Sıfat","de":"Thinking about other people's needs; or quiet because of thinking","dt":"Başkalarının ihtiyaçlarını düşünen; veya düşünceli olduğu için sessiz","e1":"It was very thoughtful of you to send flowers.","e1t":"Çiçek göndermen çok nazikçe bir davranıştı.","e2":"A thoughtful expression.","e2t":"Düşünceli bir ifade."},{"w":"thrash","tr":"dövmek / yenmek / çırpınmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit someone repeatedly; or to defeat easily","dt":"Birini defalarca vurmak; veya kolayca yenmek","e1":"Our team thrashed them 5","e1t":"0.","e2":"Takımımız onları 5","e2t":"0 bozguna uğrattı (yendi)."},{"w":"thread","tr":"iplik / konu akışı / diş (vida) / takmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long thin piece of cotton or silk; or a connected series of thoughts","dt":"Uzun ince pamuk veya ipek parçası; veya bağlantılı düşünceler serisi","e1":"Needle and thread.","e1t":"İğne iplik.","e2":"To lose the thread of a conversation.","e2t":"Konuşmanın ipinin ucunu (konu akışını) kaçırmak."},{"w":"threat","tr":"tehdit / tehlike","te":"Noun","tt":"İsim","de":"A suggestion that something unpleasant will happen","dt":"Nahoş bir şeyin olacağına dair işaret (tehdit)","e1":"To make a threat against someone.","e1t":"Birine tehditte bulunmak.","e2":"A threat to national security.","e2t":"Ulusal güvenliğe yönelik bir tehdit."},{"w":"threaten","tr":"tehdit etmek / korkutmak / tehlike arz etmek","te":"Verb","tt":"Fiil","de":"To tell someone that you will hurt them","dt":"Birine zarar vereceğini söylemek (tehdit etmek)","e1":"He threatened to resign.","e1t":"İstifa etmekle tehdit etti.","e2":"Dark clouds threatened rain.","e2t":"Kara bulutlar yağmuru haber veriyordu (yağmur tehdidi vardı)."},{"w":"threshold","tr":"eşik / sınır / başlangıç","te":"Noun","tt":"İsim","de":"The floor of an entrance; or the level at which something starts","dt":"Girişin zemini; veya bir şeyin başladığı seviye","e1":"On the threshold of a new era.","e1t":"Yeni bir çağın eşiğinde.","e2":"Pain threshold.","e2t":"Acı eşiği."},{"w":"thrifty","tr":"tutumlu / idareli","te":"Adjective","tt":"Sıfat","de":"Careful about spending money","dt":"Para harcama konusunda dikkatli","e1":"A thrifty housewife.","e1t":"Tutumlu bir ev hanımı.","e2":"Thrifty habits.","e2t":"İdareli (tutumlu) alışkanlıklar."},{"w":"thrill","tr":"heyecan / titretmek / heyecanlandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling of excitement or pleasure","dt":"Güçlü bir heyecan veya zevk hissi","e1":"The thrill of winning.","e1t":"Kazanmanın heyecanı.","e2":"It was a real thrill to meet him.","e2t":"Onunla tanışmak gerçek bir heyecandı."},{"w":"thriller","tr":"gerilim (kitap/film)","te":"Noun","tt":"İsim","de":"A book or movie with an exciting story, often about crime","dt":"Genellikle suç hakkında olan heyecan verici hikayeye sahip kitap veya film","e1":"A psychological thriller.","e1t":"Psikolojik gerilim.","e2":"To watch a thriller.","e2t":"Bir gerilim filmi izlemek."},{"w":"thrive","tr":"gelişmek / serpilmek / işleri yolunda gitmek","te":"Verb","tt":"Fiil","de":"To grow or develop very well","dt":"Çok iyi büyümek veya gelişmek","e1":"Children thrive on love and attention.","e1t":"Çocuklar sevgi ve ilgiyle gelişir (serpilir).","e2":"The business is thriving.","e2t":"İşler tıkırında (gelişiyor)."},{"w":"throat","tr":"boğaz","te":"Noun","tt":"İsim","de":"The front of the neck or the passage for food and air","dt":"Boynun ön kısmı veya yemek ve hava yolu","e1":"A sore throat.","e1t":"Boğaz ağrısı.","e2":"To clear one's throat.","e2t":"Boğazını temizlemek."},{"w":"throb","tr":"zonklamak / çarpmak / zonklama","te":"Verb/Noun","tt":"Fiil/İsim","de":"To produce a strong regular beat","dt":"Güçlü ve düzenli bir atış (vuruş) üretmek","e1":"My head is throbbing with pain.","e1t":"Başım ağrıdan zonkluyor.","e2":"The throb of the engine.","e2t":"Motorun düzenli gürültüsü (atışı)."},{"w":"throne","tr":"taht","te":"Noun/Verb","tt":"İsim/Fiil","de":"A special chair used by a king or queen","dt":"Kral veya kraliçe tarafından kullanılan özel koltuk","e1":"To ascend the throne.","e1t":"Tahta çıkmak.","e2":"The heir to the throne.","e2t":"Tahtın varisi."},{"w":"throng","tr":"kalabalık / üşüşmek / doluşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large group of people (literary)","dt":"Büyük insan grubu (edebi)","e1":"Throngs of people gathered in the square.","e1t":"Meydanda insan kalabalıkları toplandı.","e2":"Fans thronged the stadium.","e2t":"Hayranlar stadyuma doluştu."},{"w":"throttle","tr":"boğmak / gaz vermek / vana / gaz kolu","te":"Verb/Noun","tt":"Fiil/İsim","de":"To press someone's throat; or the control for fuel in an engine","dt":"Birinin boğazını sıkmak; veya motordaki yakıt kontrolü","e1":"To throttle someone to death.","e1t":"Birini boğarak öldürmek.","e2":"Full throttle (at maximum speed).","e2t":"Tam gaz."},{"w":"throughout","tr":"boyunca / her tarafında","te":"Prep/Adverb","tt":"In every part of a place; or during the whole period of time","de":"Bir yerin her tarafında; veya tüm zaman boyunca","dt":"Throughout the world.","e1":"Dünya genelinde (her yerinde).","e1t":"Throughout the year.","e2":"Yıl boyunca.","e2t":""},{"w":"thrust","tr":"itmek / dürtmek / hamle / itiş gücü","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push something suddenly and with force","dt":"Bir şeyi aniden ve güçle itmek","e1":"He thrust the money into my hand.","e1t":"Parayı elime tutuşturdu (itti).","e2":"The main thrust of the argument.","e2t":"İddianın ana ekseni (itiş noktası)."},{"w":"thump","tr":"küt diye vurmak / gümlemek / gümleme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To hit something with a heavy dull sound","dt":"Ağır ve boğuk bir sesle bir şeye vurmak","e1":"He thumped the table with his fist.","e1t":"Yumruğuyla masaya küt diye vurdu.","e2":"My heart was thumping.","e2t":"Kalbim güm güm atıyordu."},{"w":"thunder","tr":"gök gürültüsü / gürlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The loud noise that you hear after a flash of lightning","dt":"Şimşekten sonra duyulan yüksek ses","e1":"Thunder and lightning.","e1t":"Gök gürültüsü ve şimşek.","e2":"A clap of thunder.","e2t":"Bir gök gürlemesi."},{"w":"thunderstorm","tr":"gök gürültülü fırtına","te":"Noun","tt":"İsim","de":"A storm with thunder and lightning","dt":"Gök gürültüsü ve şimşekli fırtına","e1":"We were caught in a violent thunderstorm.","e1t":"Şiddetli bir fırtınaya yakalandık.","e2":"To forecast a thunderstorm.","e2t":"Gök gürültülü fırtına tahmin etmek."},{"w":"tick","tr":"tıkırtı / işaret (onay) / kene / işaretlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short sound like a clock; or a mark (✓)","dt":"Saat sesi gibi kısa bir ses; veya onay işareti (✓)","e1":"The tick of the clock.","e1t":"Saatin tıkırtısı.","e2":"Put a tick next to the correct answer.","e2t":"Doğru cevabın yanına bir işaret koyun."},{"w":"ticket","tr":"bilet / etiket / ceza makbuzu / bilet kesmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of paper that gives you a right","dt":"Size hak veren küçük kağıt parçası","e1":"A one","e1t":"way ticket.","e2":"Gidiş bileti.","e2t":"A speeding ticket."},{"w":"tickle","tr":"gıdıklamak / gıdıklanmak / kaşınmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To touch someone in a way that makes them laugh","dt":"Birine güldürecek şekilde dokunmak","e1":"Stop tickling me!","e1t":"Beni gıdıklamayı bırak!","e2":"My throat tickles.","e2t":"Boğazım gıdıklanıyor (kaşınıyor)."},{"w":"tide","tr":"gelgit / akıntı / gidişat","te":"Noun/Verb","tt":"İsim/Fiil","de":"The regular rise and fall of the level of the sea","dt":"Deniz seviyesinin düzenli yükselip alçalması","e1":"High tide / Low tide.","e1t":"Med / Cezir (Yüksek/Alçak gelgit).","e2":"To turn the tide.","e2t":"Gidişatı değiştirmek."},{"w":"tidy","tr":"düzenli / tertipli / toplamak","te":"Adjective/Verb/Noun","tt":"Having everything in its right place","de":"Her şeyin yerli yerinde olması","dt":"A tidy room.","e1":"Düzenli bir oda.","e1t":"To tidy up the house.","e2":"Evi toparlamak.","e2t":""},{"w":"tier","tr":"kat / tabaka / aşama","te":"Noun/Verb","tt":"İsim/Fiil","de":"One of several layers or levels","dt":"Birkaç katman veya seviyeden biri","e1":"A wedding cake with three tiers.","e1t":"Üç katlı düğün pastası.","e2":"A multi","e2t":"tier system."},{"w":"tile","tr":"fayans / karo / kiremit / döşemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A flat piece of baked clay used for walls or roofs","dt":"Duvar veya çatılar için kullanılan düz pişmiş toprak parçası","e1":"Roof tiles.","e1t":"Çatı kiremitleri.","e2":"Bathroom tiles.","e2t":"Banyo fayansları."},{"w":"tilt","tr":"eğmek / yatırmak / eğim","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move into a sloping position","dt":"Eğik bir konuma getirmek","e1":"To tilt your head to one side.","e1t":"Başını bir yana eğmek.","e2":"The table is at a slight tilt.","e2t":"Masa hafifçe eğik duruyor."},{"w":"timber","tr":"kereste / kalas / ağaç (kesilecek)","te":"Noun/Intj","tt":"Wood used for building; or a warning when a tree falls","de":"İnşaat için kullanılan odun; veya ağaç devrilirken yapılan uyarı","dt":"A timber merchant.","e1":"Kereste tüccarı.","e1t":"To build a house with timber.","e2":"Keresteyle ev inşa etmek.","e2t":""},{"w":"timid","tr":"ürkek / çekingen / utangaç","te":"Adjective","tt":"Sıfat","de":"Shy and easily frightened","dt":"Utangaç ve kolayca korkan","e1":"A timid child.","e1t":"Ürkek bir çocuk.","e2":"As timid as a mouse.","e2t":"Fare kadar ürkek."},{"w":"timing","tr":"zamanlama","te":"Noun","tt":"İsim","de":"The choice of when something should happen","dt":"Bir şeyin ne zaman olması gerektiği seçimi","e1":"Perfect timing.","e1t":"Mükemmel zamanlama.","e2":"The timing of the announcement was poor.","e2t":"Duyurunun zamanlaması kötüydü."},{"w":"tinge","tr":"hafif renk / esinti / belirti / hafifçe boyamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very small amount of a color or feeling","dt":"Rengin veya duygunun çok küçük bir miktarı","e1":"A tinge of sadness in her voice.","e1t":"Sesinde hafif bir hüzün.","e2":"White with a pink tinge.","e2t":"Pembe esintili (hafif pembe) beyaz."},{"w":"tingle","tr":"karıncalanmak / ürpermek / sızı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To have a feeling as if many sharp points are being pushed into skin","dt":"Cilde birçok keskin ucun batıyormuş gibi hissedilmesi","e1":"My fingers tingled with the cold.","e1t":"Parmaklarım soğuktan karıncalandı.","e2":"A tingle of excitement.","e2t":"Heyecan ürpertisi."},{"w":"tint","tr":"renk tonu / hafifçe boyamak / (cam) film çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small amount of a color; or to dye slightly","dt":"Bir rengin az miktarı; veya hafifçe boyamak","e1":"To tint your hair.","e1t":"Saçı hafifçe boyamak (tonlamak).","e2":"Tinted windows.","e2t":"Filmli (renkli) camlar."},{"w":"tiny","tr":"küçücük / minicik","te":"Adjective","tt":"Sıfat","de":"Very small","dt":"Çok küçük","e1":"A tiny insect.","e1t":"Minicik bir böcek.","e2":"A tiny bit of sugar.","e2t":"Çok azıcık şeker."},{"w":"tip","tr":"ipucu / bahşiş / uç / devirmek / çöplük","te":"Noun/Verb","tt":"İsim/Fiil","de":"A useful piece of advice; or extra money; or the end","dt":"Faydalı tavsiye; veya ekstra para; veya uç","e1":"Useful tips for travelers.","e1t":"Gezginler için faydalı ipuçları.","e2":"To leave a generous tip.","e2t":"Cömert bir bahşiş bırakmak."},{"w":"tissue","tr":"doku / kağıt mendil / ince kumaş","te":"Noun","tt":"İsim","de":"A group of cells; or a soft piece of paper","dt":"Hücre grubu; veya yumuşak kağıt parçası","e1":"Muscle tissue.","e1t":"Kas dokusu.","e2":"A box of tissues.","e2t":"Bir kutu kağıt mendil."},{"w":"toil","tr":"zahmetli iş / didinmek / uğraşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Hard work that makes you very tired","dt":"Sizi çok yoran ağır iş","e1":"Years of toil in the fields.","e1t":"Tarlalarda geçen didinme dolu yıllar.","e2":"To toil away at a task.","e2t":"Bir iş üzerinde uğraşıp durmak (didinmek)."},{"w":"token","tr":"jeton / simge / belirti / sembolik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A round piece of metal used instead of money; or a sign","dt":"Para yerine kullanılan metal parça; veya bir işaret/simge","e1":"A token of my appreciation.","e1t":"Takdirimin bir nişanesi (belirtisi).","e2":"To use tokens for the subway.","e2t":"Metro için jeton kullanmak."},{"w":"tolerance","tr":"hoşgörü / tolerans / dayanıklılık / tolerans payı","te":"Noun","tt":"İsim","de":"The ability to accept beliefs that are different from your own","dt":"Farklı inançları kabul etme yeteneği","e1":"Religious tolerance.","e1t":"Dini hoşgörü.","e2":"To have a high tolerance for pain.","e2t":"Acıya karşı yüksek dayanıklılığa (toleransa) sahip olmak."},{"w":"tolerant","tr":"hoşgörülü / toleranslı / dayanıklı","te":"Adjective","tt":"Sıfat","de":"Willing to accept behavior that you do not agree with","dt":"Katılmadığınız davranışları kabul etmeye istekli","e1":"To be tolerant of other people's opinions.","e1t":"Diğer insanların fikirlerine karşı hoşgörülü olmak.","e2":"Drought","e2t":"tolerant plants."},{"w":"tolerate","tr":"katlanmak / tahammül etmek / hoş görmek","te":"Verb","tt":"Fiil","de":"To accept something that you do not like","dt":"Sevmediğiniz bir şeyi kabul etmek (katlanmak)","e1":"I won't tolerate such behavior.","e1t":"Bu tarz bir davranışa müsamaha göstermeyeceğim (tahammül etmeyeceğim).","e2":"To tolerate a drug.","e2t":"Bir ilaca karşı dirençli olmak (vücudun kaldırması)."},{"w":"toll","tr":"geçiş ücreti / bedel / ölü sayısı / (çan) çalmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Money you pay to use a road; or the suffering caused by something","dt":"Yol kullanımı için ödenen para; veya bir şeyin neden olduğu acı/kayıp","e1":"A toll road.","e1t":"Ücretli yol.","e2":"The death toll from the earthquake.","e2t":"Depremdeki ölü sayısı."},{"w":"tonic","tr":"tonik / canlandırıcı / şifalı içecek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something that makes you feel stronger or happier","dt":"Sizi daha güçlü veya mutlu hissettiren şey","e1":"The holiday was a real tonic for her.","e1t":"Tatil ona gerçekten ilaç (canlandırıcı) gibi geldi.","e2":"Gin and tonic.","e2t":"Cin tonik."},{"w":"topography","tr":"topografya / yer şekilleri","te":"Noun","tt":"İsim","de":"The physical features of an area of land","dt":"Bir arazi alanının fiziksel özellikleri","e1":"The topography of the region.","e1t":"Bölgenin topografyası (yer şekilleri).","e2":"Topographical map.","e2t":"Topografik harita."},{"w":"torch","tr":"el feneri (UK) / meşale / yakmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small electric light held in the hand; or a burning stick","dt":"Elde tutulan küçük elektrikli ışık; veya yanan sopa","e1":"To shine a torch.","e1t":"El feneri tutmak (yakmak).","e2":"The Olympic torch.","e2t":"Olimpiyat meşalesi."},{"w":"torment","tr":"azap / eziyet / eziyet etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great mental or physical suffering","dt":"Büyük zihinsel veya fiziksel acı","e1":"The memory of the accident was a constant torment.","e1t":"Kaza hatırası sürekli bir azaptı.","e2":"To be tormented by guilt.","e2t":"Suçluluk duygusuyla kıvranmak (eziyet çekmek)."},{"w":"tornado","tr":"hortum / kasırga","te":"Noun","tt":"İsim","de":"A strong wind that spins very fast in a funnel shape","dt":"Huni şeklinde çok hızlı dönen güçlü rüzgâr","e1":"The tornado destroyed several houses.","e1t":"Hortum birkaç evi yıktı.","e2":"Tornado warning.","e2t":"Hortum uyarısı."},{"w":"torpedo","tr":"torpido / torpillemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A weapon that travels underwater to hit a ship","dt":"Gemiye vurmak için su altında ilerleyen silah","e1":"The submarine fired a torpedo.","e1t":"Denizaltı bir torpido fırlattı.","e2":"To torpedo a plan (to destroy it).","e2t":"Bir planı baltalamak (torpillemek)."},{"w":"torrent","tr":"sel / sağanak / tufan","te":"Noun","tt":"İsim","de":"A large amount of water moving quickly; or a sudden flow of words","dt":"Hızla hareket eden büyük miktarda su; veya ani kelime akışı","e1":"The rain fell in torrents.","e1t":"Yağmur bardaktan boşalırcasına (sel gibi) yağdı.","e2":"A torrent of abuse.","e2t":"Küfür (hakaret) tufanı."},{"w":"torture","tr":"işkence / işkence etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The act of causing great physical pain as a punishment","dt":"Ceza olarak büyük fiziksel acı verme eylemi","e1":"To die under torture.","e1t":"İşkence altında ölmek.","e2":"It was torture waiting for the results.","e2t":"Sonuçları beklemek bir işkenceydi."},{"w":"toss","tr":"atmak / fırlatmak / yazı tura atmak / çalkalanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To throw something carelessly","dt":"Bir şeyi dikkatsizce atmak","e1":"To toss a coin.","e1t":"Yazı tura atmak.","e2":"Toss the salad.","e2t":"Salatayı karıştırmak."},{"w":"tough","tr":"sert / zorlu / dayanıklı / kabadayı","te":"Adjective/Noun/Adv/Verb","tt":"Strong and not easily broken; or difficult","de":"Güçlü ve kolay kırılmayan; veya zor","dt":"A tough decision.","e1":"Zor bir karar.","e1t":"Tough meat.","e2":"Sert et.","e2t":""},{"w":"tournament","tr":"turnuva","te":"Noun","tt":"İsim","de":"A competition with many players or teams","dt":"Birçok oyuncu veya takımın katıldığı yarışma","e1":"A tennis tournament.","e1t":"Tenis turnuvası.","e2":"To win the tournament.","e2t":"Turnuvayı kazanmak."},{"w":"tow","tr":"çekmek (araç) / yedekte çekme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull a vehicle or boat behind another one","dt":"Bir aracı veya tekneyi diğerinin arkasından çekmek","e1":"My car was towed away.","e1t":"Arabam çekildi.","e2":"A tow truck.","e2t":"Çekici (kurtarıcı)."},{"w":"toxic","tr":"zehirli / toksik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Poisonous; or very unpleasant or harmful","dt":"Zehirli; veya çok nahoş veya zararlı","e1":"Toxic waste.","e1t":"Zehirli atık.","e2":"A toxic relationship.","e2t":"Toksik (zararlı) bir ilişki."},{"w":"trace","tr":"iz / belirti / izini sürmek / kopya etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sign that something has happened or existed; or to find","dt":"Bir şeyin olduğuna dair işaret; veya bulmak","e1":"No trace of the missing person.","e1t":"Kayıp kişiden hiçbir iz yok.","e2":"To trace your ancestors.","e2t":"Atalarının izini sürmek."},{"w":"track","tr":"iz / yol / parkur / takip etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A path or line of marks; or to follow progress","dt":"Yol veya iz hattı; veya ilerlemeyi takip etmek","e1":"Railway track.","e1t":"Tren rayı.","e2":"To keep track of time.","e2t":"Zamanı takip etmek."},{"w":"tract","tr":"alan / bölge / kanal (vücut) / kitapçık","te":"Noun","tt":"İsim","de":"A large area of land; or a system of organs","dt":"Geniş arazi alanı; veya organlar sistemi","e1":"Vast tracts of forest.","e1t":"Uçsuz bucaksız orman alanları.","e2":"Digestive tract.","e2t":"Sindirim sistemi (kanalı)."},{"w":"traction","tr":"çekiş / sürtünme / ilgi / çekme (tıp)","te":"Noun","tt":"İsim","de":"The ability of a wheel to grip the ground; or support for a plan","dt":"Bir tekerleğin yeri kavrama yeteneği; veya bir planın destek görmesi","e1":"The tires have good traction on ice.","e1t":"Lastiklerin buzda çekişi (tutuşu) iyi.","e2":"The idea is starting to gain traction.","e2t":"Fikir ilgi görmeye (yayılmaya) başlıyor."},{"w":"tragedy","tr":"trajedi / facia","te":"Noun","tt":"İsim","de":"A very sad event or a play with a sad ending","dt":"Çok üzücü bir olay veya sonu kötü biten oyun","e1":"The accident was a great tragedy.","e1t":"Kaza büyük bir trajediydi.","e2":"Greek tragedy.","e2t":"Yunan trajedisi."},{"w":"trail","tr":"iz / patika / sürüklenmek / izini sürmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A path through the countryside; or a series of marks","dt":"Kırsal alandaki patika; veya bir dizi iz","e1":"A forest trail.","e1t":"Orman patikası.","e2":"A trail of blood.","e2t":"Kan izi."},{"w":"trailer","tr":"römork / karavan / fragman","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vehicle pulled by another; or a short film for a movie","dt":"Başka bir araçla çekilen araç; veya bir film için kısa tanıtım","e1":"A boat trailer.","e1t":"Tekne römorku.","e2":"I saw the trailer for the new movie.","e2t":"Yeni filmin fragmanını gördüm."},{"w":"trait","tr":"özellik / kişisel nitelik / karakter özelliği","te":"Noun","tt":"İsim","de":"A particular characteristic of someone's character","dt":"Birinin karakterine has özellik","e1":"Personality traits.","e1t":"Kişilik özellikleri.","e2":"A genetic trait.","e2t":"Genetik bir özellik."},{"w":"traitor","tr":"hain","te":"Noun","tt":"İsim","de":"A person who is not loyal to their country or friends","dt":"Ülkesine veya arkadaşlarına sadık olmayan kişi","e1":"He was branded a traitor.","e1t":"Hain olarak damgalandı.","e2":"Traitor to the cause.","e2t":"Davaya ihanet eden kişi."},{"w":"trajectory","tr":"yörünge / izlenen yol","te":"Noun","tt":"İsim","de":"The curved path of an object through the air","dt":"Bir nesnenin havada izlediği kavisli yol","e1":"The trajectory of the missile.","e1t":"Füzenin yörüngesi.","e2":"Career trajectory.","e2t":"Kariyer yolu (gelişimi)."},{"w":"tram","tr":"tramvay","te":"Noun/Verb","tt":"İsim/Fiil","de":"An electric vehicle that travels on rails in city streets","dt":"Şehir sokaklarındaki raylar üzerinde giden elektrikli araç","e1":"To take the tram.","e1t":"Tramvaya binmek.","e2":"Tram lines.","e2t":"Tramvay hatları."},{"w":"tramp","tr":"serseri / aylak / ağır adım / doğa yürüyüşü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person with no home who travels from place to place","dt":"Yerden yere gezen evsiz kişi","e1":"To hear the tramp of feet.","e1t":"Ayak seslerini (ağır adımları) duymak.","e2":"A long tramp through the hills.","e2t":"Tepelerde uzun bir yürüyüş."},{"w":"trance","tr":"trans / kendinden geçme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A state of being half","dt":"asleep or not aware of surroundings","e1":"Yarı uykulu olma veya çevrenin farkında olmama durumu","e1t":"He was in a deep trance.","e2":"Derin bir transtaydı.","e2t":"Hypnotic trance."},{"w":"tranquil","tr":"huzurlu / sakin / dingin","te":"Adjective","tt":"Sıfat","de":"Calm and peaceful and without noise","dt":"Sakin, huzurlu ve gürültüsüz","e1":"A tranquil village.","e1t":"Huzurlu bir köy.","e2":"To lead a tranquil life.","e2t":"Sakin bir hayat sürmek."},{"w":"tranquility / tranquillity","tr":"huzur / sükunet / sakinlik","te":"Noun","tt":"İsim","de":"The quality of being calm and peaceful","dt":"Sakin ve huzurlu olma niteliği","e1":"The tranquility of the countryside.","e1t":"Kırsalın huzuru.","e2":"To enjoy the tranquility.","e2t":"Sükunetin tadını çıkarmak."},{"w":"transact","tr":"işlem yapmak / yürütmek","te":"Verb","tt":"Fiil","de":"To do business with another person or company","dt":"Başka bir kişi veya şirketle iş yapmak","e1":"Most of our business is transacted online.","e1t":"İşlerimizin çoğu çevrimiçi ortamda yürütülüyor.","e2":"To transact a deal.","e2t":"Bir anlaşma gerçekleştirmek."},{"w":"transaction","tr":"işlem / muamele","te":"Noun","tt":"İsim","de":"An occasion when people buy or sell something","dt":"İnsanların bir şey alıp sattığı durum (işlem)","e1":"Financial transactions.","e1t":"Finansal işlemler.","e2":"A business transaction.","e2t":"Ticari bir muamele."},{"w":"transcribe","tr":"yazıya dökmek / kopyalamak","te":"Verb","tt":"Fiil","de":"To record something in writing","dt":"Bir şeyi yazılı olarak kaydetmek","e1":"To transcribe a speech.","e1t":"Bir konuşmayı yazıya dökmek.","e2":"The biologist transcribed the genetic code.","e2t":"Biyolog genetik kodu kopyaladı (aktardı)."},{"w":"transcript","tr":"döküm / kopya / not dökümü","te":"Noun","tt":"İsim","de":"A written record of words that have been spoken","dt":"Konuşulan kelimelerin yazılı kaydı","e1":"A transcript of the interview.","e1t":"Mülakatın dökümü.","e2":"Official academic transcript.","e2t":"Resmi akademik not dökümü (transkript)."},{"w":"transfer","tr":"aktarmak / transfer etmek / geçiş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move someone or something from one place to another","dt":"Birini veya bir şeyi bir yerden başka bir yere taşımak","e1":"To transfer money to a bank account.","e1t":"Banka hesabına para aktarmak.","e2":"A bus transfer.","e2t":"Otobüs aktarması."},{"w":"transform","tr":"dönüştürmek / şeklini değiştirmek","te":"Verb","tt":"Fiil","de":"To change something completely, especially its appearance","dt":"Bir şeyi, özellikle görünüşünü tamamen değiştirmek","e1":"The house was transformed into a museum.","e1t":"Ev bir müzeye dönüştürüldü.","e2":"Technology has transformed our lives.","e2t":"Teknoloji hayatlarımızı dönüştürdü."},{"w":"transformation","tr":"dönüşüm / değişim","te":"Noun","tt":"İsim","de":"A complete change in the appearance or character of something","dt":"Bir şeyin görünüşünde veya karakterinde tam bir değişim","e1":"A physical transformation.","e1t":"Fiziksel bir dönüşüm.","e2":"The transformation of the economy.","e2t":"Ekonominin dönüşümü."},{"w":"transformer","tr":"transformatör / trafo","te":"Noun","tt":"İsim","de":"A device used for changing the voltage of electricity","dt":"Elektrik voltajını değiştirmek için kullanılan cihaz","e1":"An electrical transformer.","e1t":"Elektrik trafosu.","e2":"The movie \"Transformers\".","e2t":"\"Transformers\" filmi."},{"w":"transfusion","tr":"kan nakli / enjeksiyon","te":"Noun","tt":"İsim","de":"The act of putting someone else's blood into a person","dt":"Bir kişinin kanını başka birine verme eylemi","e1":"He needed a blood transfusion after the accident.","e1t":"Kazadan sonra kan nakline ihtiyacı oldu.","e2":"A life","e2t":"saving transfusion."},{"w":"transient","tr":"geçici / anlık / konuk","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Lasting for only a short time; or a person staying a short time","dt":"Sadece kısa bir süre süren; veya kısa süre kalan kişi","e1":"Transient feelings of happiness.","e1t":"Geçici mutluluk hisleri.","e2":"A transient population.","e2t":"Hareketli (geçici) bir nüfus."},{"w":"transistor","tr":"transistör","te":"Noun","tt":"İsim","de":"A small electrical device used in radios and computers","dt":"Radyo ve bilgisayarlarda kullanılan küçük elektrikli cihaz","e1":"The invention of the transistor.","e1t":"Transistörün icadı.","e2":"Transistor radio.","e2t":"Transistörlü radyo."},{"w":"transit","tr":"geçiş / taşıma / transit","te":"Noun/Verb","tt":"İsim/Fiil","de":"The movement of goods or people from one place to another","dt":"Malların veya insanların bir yerden bir yere hareketi","e1":"Mass transit (public transport).","e1t":"Toplu taşıma.","e2":"Goods lost in transit.","e2t":"Taşıma (nakliye) sırasında kaybolan mallar."},{"w":"transition","tr":"geçiş / değişim süreci","te":"Noun/Verb","tt":"İsim/Fiil","de":"A change from one system or state to another","dt":"Bir sistemden veya durumdan diğerine değişim","e1":"The transition from childhood to adulthood.","e1t":"Çocukluktan yetişkinliğe geçiş.","e2":"A smooth transition.","e2t":"Sorunsuz bir geçiş."},{"w":"transitive","tr":"geçişli (fiil)","te":"Adjective","tt":"Sıfat","de":"(Of a verb) having an object","dt":"(Fiil için) nesne alan","e1":"\"Eat\" is a transitive verb.","e1t":"\"Eat\" geçişli bir fiildir.","e2":"Intransitive verbs.","e2t":"Geçişsiz fiiller."},{"w":"translate","tr":"çevirmek / tercüme etmek","te":"Verb","tt":"Fiil","de":"To change words from one language into another","dt":"Kelimeleri bir dilden başka bir dile değiştirmek","e1":"To translate a book into English.","e1t":"Bir kitabı İngilizceye çevirmek.","e2":"That doesn't translate well.","e2t":"Bu tam olarak karşılamıyor (çevirisi iyi olmuyor)."},{"w":"translation","tr":"çeviri / tercüme","te":"Noun","tt":"İsim","de":"The process of changing words into another language","dt":"Kelimeleri başka bir dile değiştirme süreci","e1":"A literal translation.","e1t":"Kelimesi kelimesine çeviri.","e2":"Lost in translation.","e2t":"Çeviride kaybolan anlam."},{"w":"translator","tr":"çevirmen / mütercim","te":"Noun","tt":"İsim","de":"A person whose job is translating writing or speech","dt":"İşi yazı veya konuşma çevirmek olan kişi","e1":"Freelance translator.","e1t":"Serbest çevirmen.","e2":"Online translator.","e2t":"Çevrimiçi çeviri aracı."},{"w":"translucent","tr":"yarı saydam","te":"Adjective","tt":"Sıfat","de":"Allowing some light to pass through but not clear","dt":"Bazı ışıkların geçmesine izin veren ancak net olmayan","e1":"Translucent glass.","e1t":"Yarı saydam cam.","e2":"The skin of the onion is translucent.","e2t":"Soğanın kabuğu yarı saydamdır."},{"w":"transmission","tr":"iletim / yayın / şanzıman / bulaşma","te":"Noun","tt":"İsim","de":"The act of sending or passing something; or a vehicle part","dt":"Bir şeyi gönderme veya geçirme eylemi; veya araç parçası","e1":"The transmission of a virus.","e1t":"Bir virüsün bulaşması (yayılması).","e2":"Live transmission of the match.","e2t":"Maçın canlı yayını."},{"w":"transmit","tr":"iletmek / yayınlamak / bulaştırmak","te":"Verb","tt":"Fiil","de":"To pass something from one person or place to another","dt":"Bir şeyi bir kişiden veya yerden diğerine geçirmek","e1":"To transmit a radio signal.","e1t":"Radyo sinyali iletmek.","e2":"The disease is transmitted by mosquitoes.","e2t":"Hastalık sivrisinekler tarafından bulaştırılır."},{"w":"transparent","tr":"saydam / şeffaf / apaçık","te":"Adjective","tt":"Sıfat","de":"Able to be seen through; or easy to understand","dt":"İçinden bakılabilen; veya anlaşılması kolay","e1":"Transparent plastic.","e1t":"Şeffaf plastik.","e2":"A transparent lie.","e2t":"Apaçık bir yalan."},{"w":"transplant","tr":"nakletmek / organ nakli / (bitki) yerini değiştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move something from one place to another","dt":"Bir şeyi bir yerden başka bir yere taşımak","e1":"A heart transplant.","e1t":"Kalp nakli.","e2":"To transplant a tree.","e2t":"Bir ağacın yerini değiştirmek (başka yere dikmek)."},{"w":"transport","tr":"taşımak / nakletmek / ulaşım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move people or goods from one place to another","dt":"İnsanları veya malları bir yerden başka bir yere taşımak","e1":"Public transport.","e1t":"Toplu taşıma.","e2":"To transport goods by truck.","e2t":"Malları kamyonla taşımak."},{"w":"transportation","tr":"ulaşım / taşımacılık","te":"Noun","tt":"İsim","de":"The activity of moving people or things","dt":"İnsanları veya eşyaları taşıma faaliyeti","e1":"Modes of transportation.","e1t":"Ulaşım türleri.","e2":"The cost of transportation.","e2t":"Nakliye maliyeti."},{"w":"transpose","tr":"yer değiştirmek / (müzik) tonunu değiştirmek","te":"Verb","tt":"Fiil","de":"To change the order or position of two or more things","dt":"İki veya daha fazla şeyin sırasını veya konumunu değiştirmek","e1":"I accidentally transposed the two numbers.","e1t":"Yanlışlıkla iki sayının yerini değiştirdim.","e2":"To transpose a piece of music to a lower key.","e2t":"Bir müzik parçasını daha düşük bir tona aktarmak."},{"w":"trap","tr":"tuzak / kapana kısmak / hapsolmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device for catching animals; or a bad situation","dt":"Hayvan yakalamak için araç; veya kötü bir durum","e1":"To set a trap.","e1t":"Tuzak kurmak.","e2":"To be trapped in a burning building.","e2t":"Yanan bir binada mahsur kalmak (kapana kısılmak)."},{"w":"trauma","tr":"travma / sarsıntı","te":"Noun","tt":"İsim","de":"Severe emotional shock or physical injury","dt":"Şiddetli duygusal şok veya fiziksel yaralanma","e1":"The trauma of war.","e1t":"Savaş travması.","e2":"Head trauma.","e2t":"Kafa travması."},{"w":"traverse","tr":"katetmek / aşmak / çapraz geçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move across an area","dt":"Bir alan boyunca hareket etmek (geçmek)","e1":"The river traverses the entire country.","e1t":"Nehir tüm ülkeyi boydan boya geçer.","e2":"To traverse a mountain range.","e2t":"Bir dağ sırasını aşmak."},{"w":"tray","tr":"tepsi / tabla","te":"Noun","tt":"İsim","de":"A flat object used for carrying food or things","dt":"Yemek veya eşya taşımak için kullanılan düz nesne","e1":"A tea tray.","e1t":"Çay tepsisi.","e2":"Ash tray.","e2t":"Küllük."},{"w":"treachery","tr":"ihanet / kalleşlik","te":"Noun","tt":"İsim","de":"Behavior that involves hurting someone who trusts you","dt":"Size güvenen birine zarar vermeyi içeren davranış","e1":"An act of high treachery.","e1t":"Büyük bir ihanet eylemi.","e2":"The treachery of a friend.","e2t":"Bir arkadaşın kalleşliği."},{"w":"tread","tr":"basmak / yürümek / (lastik) diş","te":"Verb/Noun","tt":"Fiil/İsim","de":"To step on something; or the pattern on a tire","dt":"Bir şeye basmak; veya lastik üzerindeki desen","e1":"Don't tread on the grass.","e1t":"Çimlere basma.","e2":"To tread carefully.","e2t":"Dikkatli davranmak (adım atmak)."},{"w":"treason","tr":"vatana ihanet","te":"Noun","tt":"İsim","de":"The crime of helping your country's enemies","dt":"Ülkenin düşmanlarına yardım etme suçu","e1":"He was found guilty of high treason.","e1t":"Vatana ihanetten suçlu bulundu.","e2":"To commit treason.","e2t":"İhanet etmek."},{"w":"treasure","tr":"hazine / değer vermek / üstüne titremek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A collection of gold, silver, or jewels; or something very valuable","dt":"Altın, gümüş veya mücevher koleksiyonu; veya çok değerli bir şey","e1":"Buried treasure.","e1t":"Gömülü hazine.","e2":"I will always treasure our friendship.","e2t":"Dostluğumuza her zaman değer vereceğim (üstüne titreyeceğim)."},{"w":"treasury","tr":"hazine (bakanlık/yer)","te":"Noun","tt":"İsim","de":"The government department that controls the money","dt":"Parayı kontrol eden hükümet departmanı","e1":"The Secretary of the Treasury.","e1t":"Hazine Bakanı.","e2":"National treasury.","e2t":"Devlet hazinesi."},{"w":"treaty","tr":"antlaşma / pakt","te":"Noun","tt":"İsim","de":"A formal written agreement between two or more countries","dt":"İki veya daha fazla ülke arasındaki resmi yazılı anlaşma","e1":"To sign a peace treaty.","e1t":"Barış antlaşması imzalamak.","e2":"International treaty.","e2t":"Uluslararası antlaşma."},{"w":"trek","tr":"uzun ve zorlu yürüyüş / göç","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long difficult journey, especially on foot","dt":"Özellikle yürüyerek yapılan uzun ve zorlu yolculuk","e1":"A three","e1t":"day trek through the jungle.","e2":"Ormanda üç günlük zorlu bir yürüyüş.","e2t":"To trek across the mountains."},{"w":"tremble","tr":"titremek / sarsılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shake slightly, usually because you are cold or frightened","dt":"Genellikle soğuk veya korku nedeniyle hafifçe sallanmak","e1":"Her hands were trembling with fear.","e1t":"Elleri korkudan titriyordu.","e2":"To tremble with excitement.","e2t":"Heyecandan titremek."},{"w":"tremendous","tr":"muazzam / devasa / şahane","te":"Adjective","tt":"Sıfat","de":"Very large or great; or very good","dt":"Çok büyük; veya çok iyi","e1":"A tremendous amount of work.","e1t":"Muazzam miktarda iş.","e2":"You’ve done a tremendous job!","e2t":"Harika bir iş çıkardın!"},{"w":"tremor","tr":"titreme / sarsıntı (hafif)","te":"Noun","tt":"İsim","de":"A slight shaking movement","dt":"Hafif bir sallanma hareketi","e1":"An earthquake tremor.","e1t":"Deprem sarsıntısı.","e2":"To have a slight tremor in your voice.","e2t":"Sesinde hafif bir titreme olmak."},{"w":"trench","tr":"hendek / siper","te":"Noun/Verb","tt":"İsim/Fiil","de":"A narrow hole dug into the ground","dt":"Yere kazılmış dar delik","e1":"Trench warfare.","e1t":"Siper savaşı.","e2":"To dig a trench for a pipe.","e2t":"Bir boru için hendek kazmak."},{"w":"trend","tr":"trend / eğilim / akım","te":"Noun/Verb","tt":"İsim/Fiil","de":"A general development or change in a situation","dt":"Bir durumdaki genel gelişim veya değişim","e1":"Current fashion trends.","e1t":"Güncel moda trendleri.","e2":"An upward trend in sales.","e2t":"Satışlarda yukarı yönlü bir eğilim."},{"w":"trial","tr":"deneme / duruşma / yargılama / sıkıntı","te":"Noun/Verb/Adj","tt":"A legal process in a court; or a test of something","de":"Mahkemedeki yasal süreç; veya bir şeyin testi","dt":"To go on trial for murder.","e1":"Cinayetten yargılanmak.","e1t":"Clinical trials for a new drug.","e2":"Yeni bir ilaç için klinik denemeler.","e2t":""},{"w":"triangle","tr":"üçgen","te":"Noun","tt":"İsim","de":"A shape with three sides and three angles","dt":"Üç kenarı ve üç açısı olan şekil","e1":"An equilateral triangle.","e1t":"Eşkenar üçgen.","e2":"Love triangle.","e2t":"Aşk üçgeni."},{"w":"tribe","tr":"kabile / aşiret","te":"Noun","tt":"İsim","de":"A group of people who live together and share the same culture","dt":"Birlikte yaşayan ve aynı kültürü paylaşan insan grubu","e1":"A nomadic tribe.","e1t":"Göçebe bir kabile.","e2":"Native American tribes.","e2t":"Kızılderili kabileleri."},{"w":"tributary","tr":"kol (nehir) / haraç veren","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A river or stream that flows into a larger one","dt":"Daha büyüğüne akan nehir veya çay","e1":"A tributary of the Amazon.","e1t":"Amazon'un bir kolu.","e2":"Tributary states (historical).","e2t":"Haraç veren devletler."},{"w":"tribute","tr":"övgü / şükran ifadesi / haraç / yad etme","te":"Noun","tt":"İsim","de":"Something that you do or say to show respect","dt":"Saygı göstermek için yapılan veya söylenen şey","e1":"A floral tribute.","e1t":"Çelenk (çiçekli saygı ifadesi).","e2":"To pay tribute to someone.","e2t":"Birini övmek (saygılarını sunmak)."},{"w":"trickle","tr":"damlamak / sızmak / cılız akıntı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To flow slowly in a thin line","dt":"İnce bir hat halinde yavaşça akmak","e1":"Water trickled down the wall.","e1t":"Duvarın üzerinden su sızdı (damladı).","e2":"A trickle of information.","e2t":"Sızan (az miktarda) bilgi."},{"w":"trigger","tr":"tetiklemek / tetik / başlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A part of a gun that causes it to fire; or to start a process","dt":"Silahın ateşlenmesini sağlayan parça; veya bir süreci başlatmak","e1":"To pull the trigger.","e1t":"Tetiği çekmek.","e2":"Allergies can be triggered by dust.","e2t":"Alerjiler toz tarafından tetiklenebilir."},{"w":"trim","tr":"kırpmak / düzeltmek / süslemek / zinde / bakımlı","te":"Verb/Noun/Adj","tt":"To cut a small amount off something; or thin and healthy","de":"Bir şeyden az bir miktar kesmek; veya zayıf ve sağlıklı","dt":"To trim your hair.","e1":"Saçını kırpmak (düzeltmek).","e1t":"To keep your garden trim.","e2":"Bahçeni bakımlı tutmak.","e2t":""},{"w":"triple","tr":"üç kat / üçlü / üçle çarpmak","te":"Adjective/Verb/Noun","tt":"Three times as big or containing three parts","de":"Üç kat daha büyük veya üç parça içeren","dt":"A triple jump.","e1":"Üç adım atlama.","e1t":"Profits have tripled this year.","e2":"Kârlar bu yıl üç katına çıktı.","e2t":""},{"w":"triplet","tr":"üçüz","te":"Noun","tt":"İsim","de":"One of three children born at the same time to the same mother","dt":"Aynı anne tarafından aynı anda doğan üç çocuktan biri","e1":"They have identical triplets.","e1t":"Tek yumurta üçüzleri var.","e2":"To give birth to triplets.","e2t":"Üçüz doğurmak."},{"w":"triumph","tr":"zafer / başarı / galip gelmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A great victory or success","dt":"Büyük bir zafer veya başarı","e1":"A personal triumph.","e1t":"Kişisel bir başarı.","e2":"To triumph over difficulties.","e2t":"Zorluklara karşı galip gelmek."},{"w":"triumphant","tr":"zafer kazanmış / muzaffer / sevinçli","te":"Adjective","tt":"Sıfat","de":"Having won a victory or being happy about a success","dt":"Bir zafer kazanmış veya bir başarıdan dolayı mutlu olan","e1":"The triumphant team.","e1t":"Galip gelen (muzaffer) takım.","e2":"A triumphant smile.","e2t":"Mağrur (zafer kazanmış) bir gülümseme."},{"w":"trivial","tr":"önemsiz / ıvır zıvır","te":"Adjective","tt":"Sıfat","de":"Having little value or importance","dt":"Az değeri veya önemi olan","e1":"A trivial matter.","e1t":"Önemsiz bir mesele.","e2":"Don't waste time on trivial details.","e2t":"Önemsiz detaylarla vakit kaybetme."},{"w":"trolley","tr":"el arabası / servis arabası / tramvay (ABD)","te":"Noun","tt":"İsim","de":"A small vehicle on wheels used for carrying things","dt":"Eşya taşımak için kullanılan tekerlekli küçük araç","e1":"A shopping trolley.","e1t":"Market arabası.","e2":"Tea trolley.","e2t":"Çay arabası."},{"w":"troop","tr":"birlik (askeri) / topluluk / topluca gitmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of soldiers","dt":"Asker grubu","e1":"Troops were sent to the border.","e1t":"Sınıra askeri birlikler gönderildi.","e2":"Scout troop.","e2t":"İzci grubu."},{"w":"trophy","tr":"kupa / ödül / ganimet","te":"Noun","tt":"İsim","de":"A prize given to the winner of a competition","dt":"Bir yarışmanın kazananına verilen ödül","e1":"To win a trophy.","e1t":"Kupa kazanmak.","e2":"Champions League trophy.","e2t":"Şampiyonlar Ligi kupası."},{"w":"tropical","tr":"tropikal / sıcak","te":"Adjective","tt":"Sıfat","de":"Relating to the hottest parts of the world","dt":"Dünyanın en sıcak bölgeleriyle ilgili","e1":"Tropical rainforests.","e1t":"Tropikal yağmur ormanları.","e2":"Tropical fruit.","e2t":"Tropikal meyve."},{"w":"tropics","tr":"tropik bölgeler","te":"Noun","tt":"İsim","de":"The hottest parts of the world near the equator","dt":"Ekvator yakınındaki dünyanın en sıcak bölgeleri","e1":"To live in the tropics.","e1t":"Tropiklerde yaşamak.","e2":"The humid heat of the tropics.","e2t":"Tropiklerin nemli sıcağı."},{"w":"troublesome","tr":"baş belası / sorunlu / zahmetli","te":"Adjective","tt":"Sıfat","de":"Causing a lot of problems or worry","dt":"Çok fazla soruna veya endişeye neden olan","e1":"A troublesome cough.","e1t":"İnatçı (sorunlu) bir öksürük.","e2":"Troublesome children.","e2t":"Yaramaz (sorun çıkaran) çocuklar."},{"w":"trough","tr":"yalak / tekne / çukur / düşük nokta","te":"Noun","tt":"İsim","de":"A long narrow container for animals to eat from; or a low point","dt":"Hayvanların yemek yediği uzun dar kap; veya düşük nokta","e1":"A drinking trough.","e1t":"Su yalağı.","e2":"The trough of a wave.","e2t":"Dalga çukuru."},{"w":"truce","tr":"ateşkes / mütareke","te":"Noun","tt":"İsim","de":"An agreement to stop fighting for a short time","dt":"Savaşmayı kısa süreliğine durdurma anlaşması","e1":"To call a truce.","e1t":"Ateşkes ilan etmek.","e2":"A Christmas truce.","e2t":"Noel ateşkesi."},{"w":"truck","tr":"kamyon / tır / mal takas etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large road vehicle for carrying heavy things","dt":"Ağır yük taşımak için kullanılan büyük kara aracı","e1":"A delivery truck.","e1t":"Teslimat kamyonu.","e2":"Monster truck.","e2t":"Devasa tekerlekli gösteri kamyonu."},{"w":"true","tr":"doğru / gerçek / sadık","te":"Adjective/Adv/Noun/Verb","tt":"Based on facts and not imagined; or loyal","de":"Gerçeklere dayanan; veya sadık","dt":"A true story.","e1":"Gerçek bir hikaye.","e1t":"Dreams come true.","e2":"Hayaller gerçek olur.","e2t":""},{"w":"trumpet","tr":"trompet / borazan / haykırmak (fil)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A brass musical instrument","dt":"Pirinçten yapılmış müzik aleti","e1":"To play the trumpet.","e1t":"Trompet çalmak.","e2":"The elephant trumpeted.","e2t":"Fil haykırdı (borozan gibi ses çıkardı)."},{"w":"trunk","tr":"gövde (ağaç) / bagaj (ABD) / hortum (fil) / sandık","te":"Noun","tt":"İsim","de":"The main stem of a tree; or the back of a car","dt":"Ağacın ana gövdesi; veya arabanın arkası","e1":"The trunk of an oak tree.","e1t":"Bir meşe ağacının gövdesi.","e2":"Put the bags in the trunk.","e2t":"Çantaları bagaja koy."},{"w":"trustee","tr":"mütevelli / yediemin / yönetim kurulu üyesi","te":"Noun","tt":"İsim","de":"A person who controls money or property for someone else","dt":"Başkası adına parayı veya mülkü kontrol eden kişi","e1":"The board of trustees.","e1t":"Mütevelli heyeti (yönetim kurulu).","e2":"To act as a trustee.","e2t":"Yediemin olarak hareket etmek."},{"w":"trustworthy","tr":"güvenilir / itimat edilir","te":"Adjective","tt":"Sıfat","de":"Able to be trusted","dt":"Güvenilebilen","e1":"A trustworthy friend.","e1t":"Güvenilir bir arkadaş.","e2":"Is the information from a trustworthy source?","e2t":"Bilgi güvenilir bir kaynaktan mı?"},{"w":"truthful","tr":"dürüst / doğru / gerçekçi","te":"Adjective","tt":"Sıfat","de":"Honest and not containing any lies","dt":"Dürüst ve yalan içermeyen","e1":"A truthful answer.","e1t":"Dürüst (doğru) bir cevap.","e2":"To be truthful with someone.","e2t":"Birine karşı dürüst olmak."},{"w":"tub","tr":"küvet / leğen / kova / kap (yoğurt vb.)","te":"Noun","tt":"İsim","de":"A large round container for liquid or food","dt":"Sıvı veya yiyecek için büyük yuvarlak kap","e1":"A tub of margarine.","e1t":"Bir kap margarin.","e2":"To soak in the tub (bathtub).","e2t":"Küvette (suda) keyif yapmak."},{"w":"tuberculosis","tr":"tüberküloz / verem","te":"Noun","tt":"İsim","de":"A serious infectious disease that affects the lungs","dt":"Akciğerleri etkileyen ciddi bulaşıcı hastalık","e1":"He was treated for tuberculosis.","e1t":"Tüberküloz tedavisi gördü.","e2":"TB vaccination.","e2t":"Verem aşısı."},{"w":"tuck","tr":"tıkıştırmak / sokmak / katlamak / kıvrım","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push something into a small space to keep it tidy","dt":"Düzenli durması için bir şeyi küçük bir boşluğa sokmak","e1":"Tuck your shirt in.","e1t":"Gömleğini pantolonun içine sok.","e2":"She tucked the blanket around the baby.","e2t":"Battaniyeyi bebeğin etrafına sardı (sıkıştırdı)."},{"w":"tug","tr":"çekmek (sertçe) / asılmak / römorkör","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pull something quickly and forcefully","dt":"Bir şeyi hızlıca ve güçle çekmek","e1":"The child tugged at his mother's sleeve.","e1t":"Çocuk annesinin kolunu çekiştirdi.","e2":"A tug of war (game).","e2t":"Halat çekme yarışı."},{"w":"tuition","tr":"eğitim / okul ücreti / özel ders","te":"Noun","tt":"İsim","de":"Teaching, especially for a small group; or the cost of it","dt":"Özellikle küçük bir grup için eğitim; veya eğitim ücreti","e1":"Tuition fees.","e1t":"Okul harçları (üretleri).","e2":"To give private tuition in math.","e2t":"Matematikten özel ders vermek."},{"w":"tumble","tr":"yuvarlanmak / takla atmak / düşmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fall quickly and without control","dt":"Kontrolsüzce ve hızla düşmek","e1":"He tumbled down the stairs.","e1t":"Merdivenlerden aşağı yuvarlandı.","e2":"Prices tumbled on the stock market.","e2t":"Borsada fiyatlar tepetaklak oldu (düştü)."},{"w":"tumor / tumour","tr":"tümör / ur","te":"Noun","tt":"İsim","de":"A mass of cells growing in the body where they should not","dt":"Vücutta olmaması gereken yerde büyüyen hücre kitlesi","e1":"A brain tumor.","e1t":"Beyin tümörü.","e2":"Benign tumor.","e2t":"İyi huylu tümör."},{"w":"tune","tr":"melodi / ayar / akort etmek / ayarlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of musical notes; or to adjust a radio","dt":"Bir dizi müzik notası; veya radyo ayarlamak","e1":"A catchy tune.","e1t":"Akılda kalıcı bir melodi.","e2":"To tune a guitar.","e2t":"Gitarı akort etmek."},{"w":"turban","tr":"türban / sarık","te":"Noun","tt":"İsim","de":"A head covering made by winding a cloth around the head","dt":"Başa kumaş sarılarak yapılan başlık","e1":"He wore a silk turban.","e1t":"İpek bir sarık takıyordu.","e2":"A traditional Indian turban.","e2t":"Geleneksel Hint türbanı."},{"w":"turbine","tr":"türbin","te":"Noun","tt":"İsim","de":"A machine that is driven by the movement of air, water, or steam","dt":"Hava, su veya buharın hareketiyle sürülen makine","e1":"Wind turbine.","e1t":"Rüzgâr türbini.","e2":"Gas turbine engine.","e2t":"Gaz türbinli motor."},{"w":"turbulent","tr":"çalkantılı / fırtınalı / huzursuz","te":"Adjective","tt":"Sıfat","de":"Moving in an irregular and violent way; or full of confusion","dt":"Düzensiz ve şiddetli hareket eden; veya karmaşa dolu","e1":"Turbulent air (turbulence).","e1t":"Türbülanslı hava.","e2":"A turbulent period in history.","e2t":"Tarihte çalkantılı bir dönem."},{"w":"turf","tr":"çim / çimenlik / (argo) bölge","te":"Noun/Verb","tt":"İsim/Fiil","de":"Short grass and the surface of earth under it","dt":"Kısa çim ve altındaki toprak yüzeyi","e1":"Artificial turf.","e1t":"Yapay çim.","e2":"To protect your own turf.","e2t":"Kendi bölgesini (alanını) korumak."},{"w":"turmoil","tr":"karmaşa / kargaşa / hercümerç","te":"Noun","tt":"İsim","de":"A state of confusion, uncertainty, or lack of order","dt":"Karmaşa, belirsizlik veya düzensizlik durumu","e1":"Political turmoil.","e1t":"Siyasi kargaşa.","e2":"Her mind was in a turmoil.","e2t":"Zihni darmadağındı (karmaşa içindeydi)."},{"w":"turnover","tr":"ciro / işçi sirkülasyonu / altüst olma","te":"Noun","tt":"İsim","de":"The total amount of money a company receives; or the rate at which workers leave","dt":"Bir şirketin elde ettiği toplam para; veya işçilerin işten ayrılma hızı","e1":"Annual turnover.","e1t":"Yıllık ciro.","e2":"A high staff turnover.","e2t":"Yüksek personel sirkülasyonu (değişimi)."},{"w":"tutor","tr":"özel öğretmen / danışman / ders vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A teacher who works with one student or a small group","dt":"Tek bir öğrenci veya küçük bir grupla çalışan öğretmen","e1":"A private tutor.","e1t":"Özel öğretmen.","e2":"University tutor.","e2t":"Üniversite danışmanı (hocası)."},{"w":"tweed","tr":"tivit (kumaş) / tivit kumaştan yapılmış","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A thick woolen cloth with a rough surface","dt":"Yüzeyi pürüzlü kalın yünlü kumaş","e1":"A tweed jacket.","e1t":"Tivit ceket.","e2":"Traditional Scottish tweed.","e2t":"Geleneksel İskoç tiviti."},{"w":"twilight","tr":"alacakaranlık / gün batımı / çöküş dönemi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The period just before it becomes completely dark","dt":"Tamamen karanlık olmadan önceki süre","e1":"In the soft twilight.","e1t":"Hafif alacakaranlıkta.","e2":"The twilight of his career.","e2t":"Kariyerinin son demleri (çöküş dönemi)."},{"w":"twin","tr":"ikiz / eş / benzer","te":"Noun/Adj/Verb","tt":"One of two children born at the same time to the same mother","de":"Aynı anne tarafından aynı anda doğan iki çocuktan biri","dt":"Identical twins.","e1":"Tek yumurta ikizleri.","e1t":"A twin engine plane.","e2":"Çift motorlu uçak.","e2t":""},{"w":"twine","tr":"sicim / ip / sarmak / dolanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Strong string made by twisting two or more threads","dt":"İki veya daha fazla ipin bükülmesiyle yapılan güçlü sicim","e1":"A ball of twine.","e1t":"Bir yumak sicim.","e2":"The vine twined around the tree.","e2t":"Sarmaşık ağacın etrafına dolandı."},{"w":"twinkle","tr":"parıldamak / ışıldamak / pırıltı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shine with a light that changes from bright to faint","dt":"Parlaktan zayıfa değişen bir ışıkla parlamak","e1":"Stars twinkle in the sky.","e1t":"Yıldızlar gökyüzünde parıldar.","e2":"A twinkle in his eye.","e2t":"Gözündeki ışıltı."},{"w":"twist","tr":"bükmek / burkmak / döndürmek / beklenmedik gelişme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn something around into a different shape","dt":"Bir şeyi farklı bir şekle sokmak için döndürmek","e1":"To twist a wire.","e1t":"Bir teli bükmek.","e2":"I twisted my ankle.","e2t":"Ayak bileğimi burktum."},{"w":"twitch","tr":"seğirmek / aniden çekmek / kasılma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a sudden small movement with a part of the body","dt":"Vücudun bir kısmıyla ani küçük bir hareket yapmak","e1":"His eyelid began to twitch.","e1t":"Göz kapağı seğirmeye başladı.","e2":"To twitch the curtains.","e2t":"Perdeleri (hızlıca) aralamak."},{"w":"tycoon","tr":"iş adamı (çok zengin) / patron","te":"Noun","tt":"İsim","de":"A person who has succeeded in business and is very rich","dt":"İş dünyasında başarılı olmuş ve çok zengin kişi","e1":"A media tycoon.","e1t":"Medya patronu.","e2":"Property tycoon.","e2t":"Emlak kralı."},{"w":"type","tr":"tip / tür / çeşit / klavye ile yazmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A group of things or people with similar features","dt":"Benzer özelliklere sahip şeyler veya insanlar grubu","e1":"Blood type.","e1t":"Kan grubu.","e2":"What type of music do you like?","e2t":"Ne tür müzik seversin?"},{"w":"typhoid","tr":"tifo","te":"Noun","tt":"İsim","de":"A serious infectious disease spread by dirty food or water","dt":"Kirli yiyecek veya suyla yayılan ciddi bulaşıcı hastalık","e1":"To catch typhoid.","e1t":"Tifoya yakalanmak.","e2":"Typhoid fever.","e2t":"Tifo ateşi."},{"w":"typhoon","tr":"tayfun","te":"Noun","tt":"İsim","de":"A violent tropical storm in the western Pacific Ocean","dt":"Batı Pasifik Okyanusu'ndaki şiddetli tropikal fırtına","e1":"The typhoon caused massive flooding.","e1t":"Tayfun büyük sellere neden oldu.","e2":"A powerful typhoon.","e2t":"Güçlü bir tayfun."},{"w":"typical","tr":"tipik / kendine has / beklenen","te":"Adjective","tt":"Sıfat","de":"Showing all the characteristics that you would expect","dt":"Beklenen tüm özellikleri gösteren","e1":"A typical Turkish breakfast.","e1t":"Tipik bir Türk kahvaltısı.","e2":"It’s typical of him to be late.","e2t":"Geç kalması tam ona göre (ondan beklenen bir şey)."},{"w":"typify","tr":"simgelemek / örneklemek / temsil etmek","te":"Verb","tt":"Fiil","de":"To be a very good example of something","dt":"Bir şeyin çok iyi bir örneği olmak","e1":"His work typifies the style of the period.","e1t":"Eseri o dönemin tarzını simgeliyor (örneklendiriyor).","e2":"To typify a generation.","e2t":"Bir nesli temsil etmek."},{"w":"tyrant","tr":"diktatör / tiran / zalim yönetici","te":"Noun","tt":"İsim","de":"A ruler who has unlimited power and uses it cruelly","dt":"Sınırsız gücü olan ve bunu zalimce kullanan yönetici","e1":"The country was ruled by a brutal tyrant.","e1t":"Ülke acımasız bir diktatör tarafından yönetiliyordu.","e2":"Schoolyard tyrant (bully).","e2t":"Okul bahçesi zorbası."},{"w":"ultimate","tr":"nihai / en son / temel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Most extreme or important; or happening at the end","dt":"En uç veya önemli; veya sonunda gerçekleşen","e1":"The ultimate goal.","e1t":"Nihai (asıl) hedef.","e2":"The ultimate decision rests with the manager.","e2t":"Son karar müdüre aittir."},{"w":"ultimately","tr":"eninde sonunda / nihayetinde","te":"Adverb","tt":"Zarf","de":"Finally, after a series of events","dt":"Sonunda, bir dizi olaydan sonra","e1":"Ultimately, he had to resign.","e1t":"Nihayetinde istifa etmek zorunda kaldı.","e2":"The decision is ultimately yours.","e2t":"Karar eninde sonunda senindir."},{"w":"ultrasound","tr":"ultrason","te":"Noun","tt":"İsim","de":"Sound waves used to create a picture of the inside of the body","dt":"Vücudun içini görüntülemek için kullanılan ses dalgaları","e1":"To have an ultrasound scan.","e1t":"Ultrason taraması yaptırmak.","e2":"During pregnancy, an ultrasound is performed.","e2t":"Hamilelik sırasında ultrason yapılır."},{"w":"ultraviolet","tr":"morötesi / ultraviyole","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to light that has a shorter wavelength than visible light","dt":"Görünür ışıktan daha kısa dalga boyuna sahip ışıkla ilgili","e1":"Ultraviolet (UV) rays.","e1t":"Ultraviyole ışınları.","e2":"Protection against ultraviolet radiation.","e2t":"Morötesi radyasyona karşı koruma."},{"w":"unanimous","tr":"oybirliğiyle / hemfikir","te":"Adjective","tt":"Sıfat","de":"In complete agreement","dt":"Tam bir anlaşma içinde","e1":"The decision was unanimous.","e1t":"Karar oybirliğiyle alındı.","e2":"A unanimous vote.","e2t":"Oybirliğiyle yapılan oylama."},{"w":"uncertain","tr":"belirsiz / şüpheli / kararsız","te":"Adjective","tt":"Sıfat","de":"Not sure or not able to be relied on","dt":"Emin olunmayan veya güvenilemeyen","e1":"The future of the project is uncertain.","e1t":"Projenin geleceği belirsiz.","e2":"I’m uncertain about what to do.","e2t":"Ne yapacağım konusunda kararsızım."},{"w":"uncertainty","tr":"belirsizlik / şüphe","te":"Noun","tt":"İsim","de":"A situation in which something is not known","dt":"Bir şeyin bilinmediği durum","e1":"Economic uncertainty.","e1t":"Ekonomik belirsizlik.","e2":"To face a period of uncertainty.","e2t":"Bir belirsizlik dönemiyle karşı karşıya kalmak."},{"w":"uncharted","tr":"haritalanmamış / bilinmeyen / keşfedilmemiş","te":"Adjective","tt":"Sıfat","de":"(Of a place) not on a map; or not previously experienced","dt":"(Yer için) haritada olmayan; veya daha önce deneyimlenmemiş","e1":"Uncharted territory.","e1t":"Bilinmeyen alan (topraklar).","e2":"We are entering uncharted waters.","e2t":"Keşfedilmemiş sulara (bilinmezliğe) giriyoruz."},{"w":"unconditional","tr":"kayıtsız şartsız / koşulsuz","te":"Adjective","tt":"Sıfat","de":"Done without any limits or conditions","dt":"Herhangi bir sınır veya koşul olmaksızın yapılan","e1":"Unconditional love.","e1t":"Koşulsuz sevgi.","e2":"Unconditional surrender.","e2t":"Kayıtsız şartsız teslimiyet."},{"w":"unconscious","tr":"baygın / bilinçsiz / farkında olmayan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"In a state like sleep because of an injury; or not aware","dt":"Yaralanma nedeniyle uyku gibi bir durumda olma; veya farkında olmama","e1":"He was found unconscious on the floor.","e1t":"Yerde baygın halde bulundu.","e2":"The unconscious mind.","e2t":"Bilinçaltı."},{"w":"uncover","tr":"açığa çıkarmak / örtüsünü açmak","te":"Verb","tt":"Fiil","de":"To discover something that was hidden or secret","dt":"Gizli veya sır olan bir şeyi keşfetmek (açığa çıkarmak)","e1":"To uncover a plot.","e1t":"Bir komployu açığa çıkarmak.","e2":"The police uncovered a large theft ring.","e2t":"Polis büyük bir hırsızlık şebekesini ortaya çıkardı."},{"w":"underestimate","tr":"hafife almak / küçümsemek / düşük tahmin etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To think that something is smaller or less important than it is","dt":"Bir şeyin olduğundan daha küçük veya daha az önemli olduğunu düşünmek","e1":"Don't underestimate your opponent.","e1t":"Rakibini hafife alma.","e2":"To underestimate the cost of the project.","e2t":"Projenin maliyetini düşük tahmin etmek."},{"w":"undergo","tr":"maruz kalmak / geçirmek / başına gelmek","te":"Verb","tt":"Fiil","de":"To experience something that is unpleasant or difficult","dt":"Nahoş veya zor bir şeyi deneyimlemek (geçirmek)","e1":"To undergo surgery.","e1t":"Ameliyat olmak.","e2":"The country is undergoing a major change.","e2t":"Ülke büyük bir değişim geçiriyor."},{"w":"undergraduate","tr":"lisans öğrencisi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A student at a university who has not yet received a degree","dt":"Henüz derece almamış üniversite öğrencisi","e1":"Undergraduate studies.","e1t":"Lisans çalışmaları.","e2":"An undergraduate student.","e2t":"Lisans öğrencisi."},{"w":"underground","tr":"yer altı / gizli / metro (UK)","te":"Adverb/Adj/Noun","tt":"Below the surface of the earth; or secret","de":"Yerin yüzeyinin altında; veya gizli","dt":"An underground passage.","e1":"Yer altı geçidi.","e1t":"The underground movement.","e2":"Yeraltı (gizli) hareketi.","e2t":""},{"w":"underline","tr":"altını çizmek / vurgulamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To draw a line under a word; or to emphasize","dt":"Bir kelimenin altına çizgi çizmek; veya vurgulamak","e1":"Underline the keywords.","e1t":"Anahtar kelimelerin altını çizin.","e2":"The report underlines the need for reform.","e2t":"Rapor, reform ihtiyacını vurguluyor."},{"w":"underlying","tr":"temel / altında yatan","te":"Adjective","tt":"Sıfat","de":"Hidden but important; or existing under something","dt":"Gizli ama önemli; veya bir şeyin altında var olan","e1":"The underlying cause of the problem.","e1t":"Sorunun altında yatan neden.","e2":"Underlying assumptions.","e2t":"Temel varsayımlar."},{"w":"undermine","tr":"baltalamak / zayıflatmak / altını oymak","te":"Verb","tt":"Fiil","de":"To make someone or something weaker or less effective","dt":"Birini veya bir şeyi daha zayıf veya daha az etkili hale getirmek","e1":"Constant criticism undermined her confidence.","e1t":"Sürekli eleştiri onun güvenini baltaladı.","e2":"To undermine a government's authority.","e2t":"Bir hükümetin otoritesini zayıflatmak."},{"w":"underneath","tr":"altında / bir şeyin altında","te":"Preposition/Adverb/Noun","tt":"Under or below something","de":"Bir şeyin altında veya aşağısında","dt":"He wore a T","e1":"shirt underneath his sweater.","e1t":"Kazağının altına bir tişört giydi.","e2":"There was a secret compartment underneath.","e2t":"Altında gizli bir bölme vardı."},{"w":"underscore","tr":"altını çizmek / vurgulamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To draw a line under a word; or to emphasize something","dt":"Bir kelimenin altına çizgi çizmek; veya bir şeyi vurgulamak","e1":"The report underscores the importance of early education.","e1t":"Rapor, erken eğitimin önemini vurguluyor.","e2":"Please underscore the main points.","e2t":"Lütfen ana noktaların altını çizin."},{"w":"undertake","tr":"üstlenmek / girişmek / söz vermek","te":"Verb","tt":"Fiil","de":"To promise or agree to do something, especially something difficult","dt":"Bir şeyi yapmaya söz vermek veya kabul etmek (özellikle zor bir işi)","e1":"To undertake a new project.","e1t":"Yeni bir projeye girişmek.","e2":"He undertook to finish the job by Friday.","e2t":"İşi Cuma gününe kadar bitirmeyi üstlendi."},{"w":"undertaking","tr":"girişim / iş / taahhüt / cenaze levazımatçılığı","te":"Noun","tt":"İsim","de":"A job, business, or piece of work that someone decides to do","dt":"Birinin yapmaya karar verdiği iş, girişim veya taahhüt","e1":"A massive undertaking.","e1t":"Devasa bir girişim (iş).","e2":"Building the bridge was a huge undertaking.","e2t":"Köprüyü inşa etmek devasa bir işti."},{"w":"underwear","tr":"iç çamaşırı","te":"Noun","tt":"İsim","de":"Clothing worn next to the skin under other clothes","dt":"Diğer giysilerin altına, tene değecek şekilde giyilen kıyafet","e1":"Cotton underwear.","e1t":"Pamuklu iç çamaşırı.","e2":"To change your underwear.","e2t":"İç çamaşırını değiştirmek."},{"w":"underwrite","tr":"sigortalamak / finanse etmek / garanti etmek","te":"Verb","tt":"Fiil","de":"To accept financial responsibility for something","dt":"Bir şeyin finansal sorumluluğunu kabul etmek (garanti etmek)","e1":"The government agreed to underwrite the project.","e1t":"Hükümet projeyi finanse etmeyi (garantilemeyi) kabul etti.","e2":"To underwrite an insurance policy.","e2t":"Bir sigorta poliçesini onaylamak (üstlenmek)."},{"w":"undo","tr":"geri almak / çözmek / açmak / mahvetmek","te":"Verb","tt":"Fiil","de":"To open or unfasten something; or to cancel the effect of something","dt":"Bir şeyi açmak veya çözmek; veya bir şeyin etkisini iptal etmek","e1":"To undo a knot.","e1t":"Bir düğümü çözmek.","e2":"You can’t undo the past.","e2t":"Geçmişi geri alamazsın."},{"w":"undue","tr":"yersiz / aşırı / gereksiz","te":"Adjective","tt":"Sıfat","de":"More than is necessary, acceptable, or reasonable","dt":"Gerekli, kabul edilebilir veya makul olandan fazla","e1":"Undue pressure.","e1t":"Yersiz (aşırı) baskı.","e2":"To avoid undue delay.","e2t":"Gereksiz gecikmeden kaçınmak."},{"w":"undulate","tr":"dalgalanmak / dalgalı bir hal almak","te":"Verb/Adjective","tt":"To move with a smooth wavelike motion","de":"Pürüzsüz, dalga benzeri bir hareketle ilerlemek","dt":"The fields of wheat undulated in the breeze.","e1":"Buğday tarlaları esintide dalgalandı.","e1t":"Undulating hills.","e2":"Dalgalı (inişli çıkışlı) tepeler.","e2t":""},{"w":"unearth","tr":"açığa çıkarmak / kazıp çıkarmak","te":"Verb","tt":"Fiil","de":"To find something in the ground; or to discover a secret","dt":"Toprakta bir şey bulmak; veya bir sırrı ortaya çıkarmak","e1":"Artifacts unearthed during the excavation.","e1t":"Kazı sırasında gün yüzüne çıkarılan eserler.","e2":"To unearth a scandal.","e2t":"Bir skandalı açığa çıkarmak."},{"w":"uneasy","tr":"huzursuz / tedirgin / rahatsız","te":"Adjective","tt":"Sıfat","de":"Feeling worried or slightly afraid","dt":"Endişeli veya hafifçe korkmuş hissetmek","e1":"He had an uneasy feeling that he was being followed.","e1t":"Takip edildiğine dair huzursuz bir hissi vardı.","e2":"An uneasy peace.","e2t":"Eğreti (huzursuz) bir barış."},{"w":"unemployment","tr":"işsizlik","te":"Noun","tt":"İsim","de":"The state of being without a job","dt":"İşsiz olma durumu","e1":"Unemployment rate.","e1t":"İşsizlik oranı.","e2":"To claim unemployment benefits.","e2t":"İşsizlik maaşı (yardımı) talep etmek."},{"w":"uneven","tr":"engebeli / pürüzlü / dengesiz / tek (sayı)","te":"Adjective","tt":"Sıfat","de":"Not flat or smooth; or not regular","dt":"Düz veya pürüzsüz olmayan; veya düzenli olmayan","e1":"An uneven surface.","e1t":"Engebeli (pürüzlü) bir yüzey.","e2":"An uneven contest.","e2t":"Dengasiz (adaletsiz) bir yarışma."},{"w":"unfold","tr":"açılmak / gelişmek / göz önüne sermek","te":"Verb","tt":"Fiil","de":"To open something that was folded; or to develop","dt":"Katlanmış bir şeyi açmak; veya (olaylar için) gelişmek","e1":"To unfold a map.","e1t":"Bir haritayı açmak.","e2":"As the story unfolds...","e2t":"Hikaye geliştikçe (ortaya çıktıkça)..."},{"w":"uniform","tr":"üniforma / tek tip / düzenli","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A special set of clothes; or being the same in all parts","dt":"Özel kıyafet seti; veya her yerinde aynı (tek tip) olma","e1":"School uniform.","e1t":"Okul üniforması.","e2":"A uniform temperature.","e2t":"Sabit (her yerde aynı) sıcaklık."},{"w":"unify","tr":"birleştirmek / tek vücut yapmak","te":"Verb","tt":"Fiil","de":"To bring separate parts together to form a whole","dt":"Ayrı parçaları bir bütün oluşturacak şekilde bir araya getirmek","e1":"To unify a country.","e1t":"Bir ülkeyi birleştirmek.","e2":"A unifying force.","e2t":"Birleştirici bir güç."},{"w":"union","tr":"birlik / sendika / birleşme","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An organization of workers; or the act of joining together","dt":"İşçi organizasyonu (sendika); veya birleşme eylemi","e1":"Trade union.","e1t":"İşçi sendikası.","e2":"European Union.","e2t":"Avrupa Birliği."},{"w":"unique","tr":"eşsiz / benzersiz / kendine has","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Being the only one of its kind; or very special","dt":"Türünün tek örneği olan; veya çok özel","e1":"A unique opportunity.","e1t":"Eşsiz bir fırsat.","e2":"Every person’s fingerprints are unique.","e2t":"Her insanın parmak izi benzersizdir."},{"w":"unison","tr":"uyum / bir ağızdan / birlik","te":"Noun","tt":"İsim","de":"Acting or speaking together at the same time","dt":"Aynı anda birlikte hareket etme veya konuşma","e1":"To sing in unison.","e1t":"Bir ağızdan şarkı söylemek.","e2":"They responded in unison.","e2t":"Hep bir ağızdan cevap verdiler."},{"w":"unit","tr":"birim / ünite / bölük","te":"Noun","tt":"İsim","de":"A single thing or person; or a fixed amount for measuring","dt":"Tek bir şey veya kişi; veya ölçüm için sabit miktar","e1":"A unit of currency.","e1t":"Para birimi.","e2":"Intensive care unit (ICU).","e2t":"Yoğun bakım ünitesi."},{"w":"unite","tr":"birleşmek / birleştirmek","te":"Verb","tt":"Fiil","de":"To join together as a group","dt":"Bir grup olarak bir araya gelmek","e1":"The two parties united to form a government.","e1t":"İki parti hükümet kurmak için birleşti.","e2":"United we stand, divided we fall.","e2t":"Birlikten kuvvet doğar (Birlik olursak ayakta kalırız)."},{"w":"unity","tr":"birlik / bütünlük / teklik","te":"Noun","tt":"İsim","de":"The state of being joined together or in agreement","dt":"Birleşmiş veya anlaşma içinde olma durumu","e1":"National unity.","e1t":"Milli birlik.","e2":"A sense of unity.","e2t":"Birlik duygusu."},{"w":"universal","tr":"evrensel / genel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to everyone or everything in the world","dt":"Dünyadaki herkes veya her şeyle ilgili","e1":"A universal truth.","e1t":"Evrensel bir gerçek.","e2":"Universal health care.","e2t":"Genel sağlık hizmeti."},{"w":"universe","tr":"evren / kainat","te":"Noun","tt":"İsim","de":"Everything that exists, including all stars and planets","dt":"Tüm yıldızlar ve gezegenler dahil var olan her şey","e1":"The mysteries of the universe.","e1t":"Evrenin gizemleri.","e2":"In the entire universe.","e2t":"Tüm kainatta."},{"w":"university","tr":"üniversite","te":"Noun","tt":"İsim","de":"A place of higher education where people study for degrees","dt":"İnsanların derece almak için çalıştığı yükseköğretim kurumu","e1":"To go to university.","e1t":"Üniversiteye gitmek.","e2":"University professor.","e2t":"Üniversite profesörü."},{"w":"unleash","tr":"salıvermek / serbest bırakmak / tetiklemek","te":"Verb","tt":"Fiil","de":"To release a powerful force or emotion","dt":"Güçlü bir gücü veya duyguyu serbest bırakmak","e1":"The storm unleashed its fury on the town.","e1t":"Fırtına öfkesini kasabanın üzerine saldı.","e2":"To unleash a new product.","e2t":"Yeni bir ürünü piyasaya sürmek (salmak)."},{"w":"unlikely","tr":"düşük ihtimal / muhtemel olmayan","te":"Adjective","tt":"Sıfat","de":"Not expected to happen","dt":"Gerçekleşmesi beklenmeyen","e1":"An unlikely story.","e1t":"İnanılması güç (uydurma) bir hikaye.","e2":"It is unlikely that he will win.","e2t":"Kazanması düşük bir ihtimaldir."},{"w":"unload","tr":"boşaltmak (yük) / (silah) boşaltmak / kurtulmak","te":"Verb","tt":"Fiil","de":"To remove goods from a vehicle","dt":"Bir araçtan malları çıkarmak","e1":"To unload a truck.","e1t":"Bir kamyonu boşaltmak.","e2":"To unload a gun.","e2t":"Silahı boşaltmak."},{"w":"unprecedented","tr":"eşi benzeri görülmemiş / emsalsiz","te":"Adjective","tt":"Sıfat","de":"Never having happened or existed before","dt":"Daha önce hiç olmamış veya var olmamış","e1":"An unprecedented event.","e1t":"Eşi benzeri görülmemiş bir olay.","e2":"At an unprecedented rate.","e2t":"Görülmemiş bir hızla."},{"w":"unravel","tr":"çözmek / sökülmek / aydınlatmak","te":"Verb","tt":"Fiil","de":"To separate the threads of something; or to solve a mystery","dt":"Bir şeyin iplerini ayırmak; veya bir gizemi çözmek","e1":"My sweater is starting to unravel.","e1t":"Kazağım sökülmeye başlıyor.","e2":"To unravel a complex plot.","e2t":"Karmaşık bir komployu aydınlatmak (çözmek)."},{"w":"unrest","tr":"huzursuzluk / karışıklık / kargaşa","te":"Noun","tt":"İsim","de":"A state of anger or dissatisfaction, especially in public","dt":"Özellikle halk arasındaki öfke veya memnuniyetsizlik durumu","e1":"Civil unrest.","e1t":"Toplumsal karışıklık (huzursuzluk).","e2":"Industrial unrest.","e2t":"Endüstriyel (iş dünyası) huzursuzluk."},{"w":"unscrupulous","tr":"vicdansız / ahlaksız / ilkesiz","te":"Adjective","tt":"Sıfat","de":"Behaving in a dishonest or unfair way to get what you want","dt":"İstediğini elde etmek için dürüst olmayan veya adaletsiz davranan","e1":"Unscrupulous businessmen.","e1t":"Vicdansız iş adamları.","e2":"To take advantage of unscrupulous methods.","e2t":"Ahlaksız yöntemlerden yararlanmak."},{"w":"unstable","tr":"istikrarsız / dengesiz / değişken","te":"Adjective","tt":"Sıfat","de":"Likely to change or fail suddenly","dt":"Aniden değişmesi veya başarısız olması muhtemel","e1":"An unstable government.","e1t":"İstikrarsız bir hükümet.","e2":"Mentally unstable.","e2t":"Zihinsel olarak dengesiz."},{"w":"unveil","tr":"örtüsünü açmak / tanıtmak / ifşa etmek","te":"Verb","tt":"Fiil","de":"To remove a cover; or to show something for the first time","dt":"Örtüyü kaldırmak; veya bir şeyi ilk kez göstermek (tanıtmak)","e1":"To unveil a statue.","e1t":"Bir heykelin örtüsünü açmak (açılışını yapmak).","e2":"The company unveiled its new car.","e2t":"Şirket yeni arabasını tanıttı."},{"w":"up","tr":"to","te":"date","tt":"güncel / modern / en yeni","de":"Adjective","dt":"Sıfat","e1":"Including the most recent information; modern","e1t":"En son bilgileri içeren; modern","e2":"Up","e2t":"to"},{"w":"uphold","tr":"desteklemek / savunmak / (kararı) onamak","te":"Verb","tt":"Fiil","de":"To support or defend a law or decision","dt":"Bir yasayı veya kararı desteklemek veya savunmak","e1":"To uphold the law.","e1t":"Yasayı savunmak (uygulamak).","e2":"The court upheld the original decision.","e2t":"Mahkeme orijinal kararı onadı."},{"w":"upholstery","tr":"döşeme / döşemecilik","te":"Noun","tt":"İsim","de":"The soft covering on furniture like chairs and sofas","dt":"Sandalye ve kanepe gibi mobilyaların üzerindeki yumuşak kaplama","e1":"Leather upholstery.","e1t":"Deri döşeme.","e2":"To change the upholstery on the sofa.","e2t":"Kanepenin döşemesini değiştirmek."},{"w":"upkeep","tr":"bakım (gideri) / onarım","te":"Noun","tt":"İsim","de":"The cost or process of keeping something in good condition","dt":"Bir şeyi iyi durumda tutma maliyeti veya süreci","e1":"The upkeep of a large house.","e1t":"Büyük bir evin bakım gideri.","e2":"To pay for the upkeep of the garden.","e2t":"Bahçenin bakımı için ödeme yapmak."},{"w":"uplift","tr":"moral vermek / yükseltmek / kalkındırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To improve a person's mood or social conditions","dt":"Bir kişinin ruh halini veya sosyal koşullarını iyileştirmek","e1":"His speech was very uplifting.","e1t":"Konuşması çok moral vericiydi (canlandırıcıydı).","e2":"Social uplift.","e2t":"Sosyal kalkınma."},{"w":"uprising","tr":"ayaklanma / isyan","te":"Noun","tt":"İsim","de":"An act of opposition, sometimes violent, against a government","dt":"Hükümete karşı bazen şiddet içeren muhalefet eylemi","e1":"An armed uprising.","e1t":"Silahlı ayaklanma.","e2":"To put down an uprising.","e2t":"Bir isyanı bastırmak."},{"w":"uproar","tr":"gürültü patırtı / arbede / kargaşa","te":"Noun","tt":"İsim","de":"A situation with a lot of noise and excitement or anger","dt":"Gürültü ve heyecan veya öfkenin hakim olduğu durum","e1":"The room was in an uproar.","e1t":"Odada kıyamet kopuyordu (gürültü patırtı vardı).","e2":"To cause a public uproar.","e2t":"Kamuoyunda infial (gürültü) yaratmak."},{"w":"uproot","tr":"kökünden sökmek / yerinden yurdundan etmek","te":"Verb","tt":"Fiil","de":"To pull a plant out of the ground; or to force someone to leave","dt":"Bir bitkiyi topraktan çekmek; veya birini gitmeye zorlamak","e1":"The wind uprooted several trees.","e1t":"Rüzgâr birkaç ağacı kökünden söktü.","e2":"Families uprooted by the war.","e2t":"Savaş nedeniyle yerinden yurdundan edilen aileler."},{"w":"upset","tr":"üzmek / altüst etmek / devirmek / bozuk (mide)","te":"Verb/Noun/Adj","tt":"To make someone worried or unhappy; or to knock over","de":"Birini endişelendirmek veya üzmek; veya devirmek","dt":"I didn't mean to upset you.","e1":"Seni üzmek istemedim.","e1t":"To have an upset stomach.","e2":"Midesi bozulmuş olmak.","e2t":""},{"w":"upside","tr":"down","te":"baş aşağı / ters","tt":"Adjective/Adverb","de":"Sıfat/Zarf","dt":"Having the top part at the bottom","e1":"Üst kısmı altta olan","e1t":"The picture is upside","e2":"down.","e2t":"Resim baş aşağı (ters)."},{"w":"upward","tr":"yukarı doğru","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Moving toward a higher place or level","dt":"Daha yüksek bir yer veya seviyeye doğru hareket eden","e1":"An upward trend in prices.","e1t":"Fiyatlarda yukarı yönlü bir eğilim.","e2":"To look upward.","e2t":"Yukarı bakmak."},{"w":"uranium","tr":"uranyum","te":"Noun","tt":"İsim","de":"A heavy silver","dt":"white metal used to produce nuclear energy","e1":"Nükleer enerji üretmek için kullanılan ağır gümüş","e1t":"beyaz metal","e2":"Uranium enrichment.","e2t":"Uranyum zenginleştirme."},{"w":"urban","tr":"kentsel / şehirle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to a city or town","dt":"Bir şehir veya kasabayla ilgili","e1":"Urban development.","e1t":"Kentsel gelişim.","e2":"Urban areas.","e2t":"Şehir alanları."},{"w":"urge","tr":"dürtü / ısrar etmek / teşvik etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To strongly advise someone to do something; or a strong wish","dt":"Birine bir şeyi yapmasını şiddetle tavsiye etmek; veya güçlü bir istek","e1":"I urge you to reconsider.","e1t":"Senden tekrar düşünmeni rica ediyorum (ısrar ediyorum).","e2":"I had a sudden urge to laugh.","e2t":"Aniden gülme isteği (dürtüsü) duydum."},{"w":"urgency","tr":"aciliyet / ivedilik","te":"Noun","tt":"İsim","de":"The quality of needing to be dealt with immediately","dt":"Hemen ilgilenilme gerekliliği niteliği","e1":"A matter of great urgency.","e1t":"Çok acil bir mesele.","e2":"There's no sense of urgency.","e2t":"Hiç aciliyet duygusu yok."},{"w":"urgent","tr":"acil / ivedi","te":"Adjective","tt":"Sıfat","de":"Needing immediate attention","dt":"Hemen dikkat gerektiren","e1":"An urgent message.","e1t":"Acil bir mesaj.","e2":"To be in urgent need of help.","e2t":"Acil yardıma muhtaç olmak."},{"w":"urinate","tr":"idrar yapmak / işemek","te":"Verb","tt":"Fiil","de":"To pass urine from the body","dt":"Vücuttan idrar çıkarmak","e1":"To urinate frequently.","e1t":"Sık idrar yapmak.","e2":"Urination.","e2t":"İdrar yapma."},{"w":"urine","tr":"idrar / çiş","te":"Noun","tt":"İsim","de":"The yellow liquid waste that leaves the body","dt":"Vücuttan atılan sarı sıvı atık","e1":"To give a urine sample.","e1t":"İdrar örneği vermek.","e2":"Urine test.","e2t":"İdrar testi."},{"w":"usage","tr":"kullanım / kullanım biçimi / gelenek","te":"Noun","tt":"İsim","de":"The way in which something is used or the amount used","dt":"Bir şeyin kullanılma şekli veya miktarı","e1":"English grammar and usage.","e1t":"İngilizce dilbilgisi ve kullanımı.","e2":"Water usage has increased.","e2t":"Su kullanımı arttı."},{"w":"usher","tr":"yer gösterici / mübaşir / öncülük etmek / içeri sokmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who shows people to their seats; or to lead someone","dt":"İnsanlara koltuklarını gösteren kişi; veya birine yol göstermek","e1":"The usher showed us to our seats in the theater.","e1t":"Yer gösterici tiyatroda bize koltuklarımızı gösterdi.","e2":"To usher in a new era.","e2t":"Yeni bir çağa öncülük etmek (başlatmak)."},{"w":"utensil","tr":"mutfak gereci / kap kacak / alet","te":"Noun","tt":"İsim","de":"A tool that is used in the house, especially for cooking","dt":"Evde, özellikle yemek pişirmek için kullanılan alet","e1":"Cooking utensils.","e1t":"Mutfak gereçleri.","e2":"Kitchen utensils.","e2t":"Mutfak kap kacağı."},{"w":"utilitarian","tr":"faydacı / yararcı","te":"Adjective","tt":"Sıfat","de":"Designed to be useful rather than attractive","dt":"Çekici olmaktan ziyade kullanışlı olması için tasarlanmış","e1":"Utilitarian furniture.","e1t":"Faydacı (sadece işlevsel) mobilya.","e2":"A utilitarian approach.","e2t":"Yararcı (pratik) bir yaklaşım."},{"w":"utility","tr":"kamu hizmeti / yarar / fayda / çok amaçlı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A service such as gas or electricity; or the quality of being useful","dt":"Gaz veya elektrik gibi bir hizmet; veya yararlı olma niteliği","e1":"Public utilities.","e1t":"Kamu hizmetleri (altyapı).","e2":"A utility room.","e2t":"Çamaşır odası (çok amaçlı oda)."},{"w":"utilize / utilise","tr":"faydalanmak / kullanmak / yararlanmak","te":"Verb","tt":"Fiil","de":"To use something in an effective way","dt":"Bir şeyi etkili bir şekilde kullanmak","e1":"To utilize resources.","e1t":"Kaynaklardan yararlanmak.","e2":"The solar panels utilize energy from the sun.","e2t":"Güneş panelleri güneşten gelen enerjiyi kullanır."},{"w":"utmost","tr":"en üstün / en büyük / elinden gelen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Used to emphasize how important or serious something is","dt":"Bir şeyin ne kadar önemli veya ciddi olduğunu vurgulamak için kullanılır","e1":"This is a matter of the utmost importance.","e1t":"Bu en yüksek öneme sahip bir meseledir.","e2":"To do your utmost (to try as hard as possible).","e2t":"Elinden gelenin en iyisini yapmak."},{"w":"utter","tr":"tam / kesin / söylemek / telaffuz etmek","te":"Adjective/Verb","tt":"Complete or extreme; or to say something","de":"Tam veya aşırı; veya bir şeyi söylemek","dt":"Utter chaos.","e1":"Tam (mutlak) kaos.","e1t":"He didn't utter a word.","e2":"Tek bir kelime bile söylemedi (etmedi).","e2t":""},{"w":"utterance","tr":"ifade / söylem / telaffuz","te":"Noun","tt":"İsim","de":"Something that someone says","dt":"Birinin söylediği şey","e1":"His public utterances.","e1t":"Onun kamuoyuna yönelik söylemleri (ifadeleri).","e2":"To give utterance to your feelings.","e2t":"Duygularını ifade etmek."},{"w":"utterly","tr":"tamamen / bütünüyle / büsbütün","te":"Adverb","tt":"Zarf","de":"Completely or extremely","dt":"Tamamen veya son derece","e1":"She was utterly confused.","e1t":"Kafası tamamen karışmıştı.","e2":"Utterly ridiculous.","e2t":"Büsbütün saçma."},{"w":"vacancy","tr":"boşluk / açık iş pozisyonu / boş oda","te":"Noun","tt":"İsim","de":"A job that is available; or a room in a hotel","dt":"Mevcut olan iş; veya oteldeki boş oda","e1":"We have a vacancy for a teacher.","e1t":"Bir öğretmen açığımız (boş pozisyonumuz) var.","e2":"\"No Vacancy\" sign.","e2t":"\"Boş yer yok\" tabelası."},{"w":"vacant","tr":"boş / sahipsiz / dalgın (bakış)","te":"Adjective","tt":"Sıfat","de":"(Of a seat, hotel room, or job) not being used","dt":"(Koltuk, oda veya iş için) kullanılmayan (boş)","e1":"A vacant seat on the bus.","e1t":"Otobüste boş bir koltuk.","e2":"A vacant expression.","e2t":"Dalgın (anlamsız) bir ifade."},{"w":"vacation","tr":"tatil / izin","te":"Noun/Verb","tt":"İsim/Fiil","de":"A period of time when you do not go to work or school","dt":"İşe veya okula gitmediğiniz süre","e1":"To go on vacation.","e1t":"Tatile gitmek.","e2":"Summer vacation.","e2t":"Yaz tatili."},{"w":"vaccinate","tr":"aşılamak / aşı yapmak","te":"Verb","tt":"Fiil","de":"To give a person a vaccine to prevent a disease","dt":"Bir hastalığı önlemek için birine aşı yapmak","e1":"All children should be vaccinated against polio.","e1t":"Tüm çocuklar çocuk felcine karşı aşılanmalıdır.","e2":"To get vaccinated.","e2t":"Aşı olmak."},{"w":"vaccination","tr":"aşılama / aşı","te":"Noun","tt":"İsim","de":"The act of giving someone a vaccine","dt":"Birine aşı yapma eylemi","e1":"Mass vaccination campaign.","e1t":"Kitlesel aşılama kampanyası.","e2":"Proof of vaccination.","e2t":"Aşı kanıtı (belgesi)."},{"w":"vaccine","tr":"aşı","te":"Noun","tt":"İsim","de":"A substance used to protect people against a disease","dt":"İnsanları bir hastalıktan korumak için kullanılan madde","e1":"To develop a new vaccine for the virus.","e1t":"Virüs için yeni bir aşı geliştirmek.","e2":"Covid vaccine.","e2t":"Covid aşısı."},{"w":"vacuum","tr":"vakum / boşluk / elektrikli süpürge / süpürmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A space that has no air or other gas in it","dt":"İçinde hava veya başka gaz bulunmayan alan","e1":"Vacuum cleaner.","e1t":"Elektrikli süpürge.","e2":"To vacuum the rug.","e2t":"Kilimi (elektrikli süpürgeyle) süpürmek."},{"w":"vague","tr":"belirsiz / hayal meyal / üstü kapalı","te":"Adjective","tt":"Sıfat","de":"Not clearly expressed, known, described, or decided","dt":"Net bir şekilde ifade edilmemiş veya bilinmeyen","e1":"A vague memory.","e1t":"Hayal meyal (belirsiz) bir anı.","e2":"He gave a vague answer.","e2t":"Üstü kapalı (net olmayan) bir cevap verdi."},{"w":"vain","tr":"beyhude / nafile / boşuna / kendini beğenmiş","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unsuccessful; or too proud of your appearance","dt":"Başarısız; veya görünüşüyle fazla gurur duyan","e1":"All our efforts were in vain.","e1t":"Tüm çabalarımız boşunaydı (nafileydi).","e2":"A vain man.","e2t":"Kendini beğenmiş (mağrur) bir adam."},{"w":"valid","tr":"geçerli / mantıklı / yasal","te":"Adjective","tt":"Sıfat","de":"Based on truth or a reason; or legally acceptable","dt":"Gerçeğe veya bir nedene dayalı; veya yasal olarak kabul edilebilir","e1":"A valid passport.","e1t":"Geçerli bir pasaport.","e2":"You have a valid point.","e2t":"Mantıklı (haklı) bir noktaya değiniyorsun."},{"w":"validate","tr":"doğrulamak / onaylamak / geçerli kılmak","te":"Verb","tt":"Fiil","de":"To prove that something is correct or valid","dt":"Bir şeyin doğru veya geçerli olduğunu kanıtlamak","e1":"To validate a ticket.","e1t":"Bir bileti onaylatmak (geçerli kılmak).","e2":"The data validates our theory.","e2t":"Veriler teorimizi doğruluyor."},{"w":"validity","tr":"geçerlilik / doğruluk","te":"Noun","tt":"İsim","de":"The state of being legally or officially acceptable","dt":"Yasal veya resmi olarak kabul edilebilir olma durumu","e1":"To question the validity of the results.","e1t":"Sonuçların doğruluğunu (geçerliliğini) sorgulamak.","e2":"The validity of a contract.","e2t":"Bir sözleşmenin geçerliliği."},{"w":"valley","tr":"vadi","te":"Noun","tt":"İsim","de":"An area of low land between hills or mountains","dt":"Tepeler veya dağlar arasındaki alçak arazi alanı","e1":"A deep valley.","e1t":"Derin bir vadi.","e2":"The Nile Valley.","e2t":"Nil Vadisi."},{"w":"valor / valour","tr":"yiğitlik / cesaret / kahramanlık","te":"Noun","tt":"İsim","de":"Great courage in the face of danger, especially in battle","dt":"Tehlike karşısında, özellikle savaşta gösterilen büyük cesaret","e1":"A medal for valor.","e1t":"Kahramanlık madalyası.","e2":"He showed great valor.","e2t":"Büyük yiğitlik gösterdi."},{"w":"valuable","tr":"değerli / kıymetli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Worth a lot of money; or very useful","dt":"Çok para eden; veya çok yararlı","e1":"A valuable painting.","e1t":"Değerli bir tablo.","e2":"Valuable information.","e2t":"Kıymetli (yararlı) bilgi."},{"w":"valve","tr":"vana / valf / kapakçık","te":"Noun","tt":"İsim","de":"A device that controls the flow of liquid or gas","dt":"Sıvı veya gaz akışını kontrol eden cihaz","e1":"To turn off the valve.","e1t":"Vanayı kapatmak.","e2":"Heart valve.","e2t":"Kalp kapakçığı."},{"w":"vanish","tr":"gözden kaybolmak / yok olmak","te":"Verb","tt":"Fiil","de":"To disappear suddenly","dt":"Aniden ortadan kaybolmak","e1":"The sun vanished behind the clouds.","e1t":"Güneş bulutların arkasında gözden kayboldu.","e2":"Their hopes vanished.","e2t":"Umutları yok oldu."},{"w":"vanity","tr":"kibir / gurur / beyhudelik / makyaj masası","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The quality of being too proud of your appearance","dt":"Görünüşüyle fazla gurur duyma niteliği","e1":"His vanity is annoying.","e1t":"Onun kibri rahatsız edici.","e2":"Vanity table.","e2t":"Makyaj masası."},{"w":"vapor / vapour","tr":"buhar / buğu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A gas or extremely small drops of liquid in the air","dt":"Hava içindeki gaz veya çok küçük sıvı damlacıkları","e1":"Water vapor.","e1t":"Su buharı.","e2":"Poisonous vapors.","e2t":"Zehirli gazlar (buharlar)."},{"w":"variable","tr":"değişken","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Likely to change often; or a number that can change","dt":"Sık sık değişmesi muhtemel olan; veya değişebilen sayı","e1":"The weather is very variable here.","e1t":"Hava burada çok değişkendir (değişkendir).","e2":"To identify the independent variable (math).","e2t":"Bağımsız değişkeni belirlemek."},{"w":"variance","tr":"farklılık / varyans / uyuşmazlık","te":"Noun","tt":"İsim","de":"The fact that two or more things are different","dt":"İki veya daha fazla şeyin farklı olması durumu","e1":"A variance in temperature.","e1t":"Sıcaklıkta bir farklılık.","e2":"To be at variance with (to disagree).","e2t":"İle uyuşmazlık içinde olmak (çelişmek)."},{"w":"variant","tr":"varyant / değişken / farklı tip","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something that is slightly different from other similar things","dt":"Diğer benzer şeylerden biraz farklı olan şey","e1":"A new variant of the virus.","e1t":"Virüsün yeni bir varyantı.","e2":"A spelling variant.","e2t":"Bir yazım farkı (varyantı)."},{"w":"variation","tr":"varyasyon / değişim / farklılık","te":"Noun","tt":"İsim","de":"A change in amount or level; or a different version","dt":"Miktar veya seviyedeki değişim; veya farklı bir versiyon","e1":"Variations in prices.","e1t":"Fiyatlardaki değişimler.","e2":"A variation on a theme (music).","e2t":"Bir tema üzerine varyasyon (çeşitleme)."},{"w":"varied","tr":"çeşitli / türlü türlü / değişen","te":"Adjective","tt":"Sıfat","de":"Containing many different types of things","dt":"Birçok farklı türde şey içeren","e1":"A varied diet.","e1t":"Çeşitli (dengeli) bir beslenme.","e2":"To lead a long and varied life.","e2t":"Uzun ve dolu dolu (çeşitli) bir hayat sürmek."},{"w":"variety","tr":"çeşitlilik / tür / varyete","te":"Noun","tt":"İsim","de":"The characteristic of often changing and being different","dt":"Sık sık değişme ve farklı olma özelliği","e1":"A variety of reasons.","e1t":"Çeşitli nedenler.","e2":"Variety is the spice of life.","e2t":"Çeşitlilik hayatın tuzudur (rengidir)."},{"w":"various","tr":"çeşitli / farklı / türlü","te":"Adjective","tt":"Sıfat","de":"Many different","dt":"Birçok farklı","e1":"For various reasons.","e1t":"Çeşitli nedenlerden dolayı.","e2":"There are various ways to solve the problem.","e2t":"Sorunu çözmenin çeşitli yolları var."},{"w":"varnish","tr":"vernik / cila / verniklemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A liquid that is put on wood to protect it and make it shine","dt":"Ahşabı korumak ve parlatmak için sürülen sıvı","e1":"To apply a coat of varnish.","e1t":"Bir kat vernik sürmek.","e2":"Nail varnish.","e2t":"Oje."},{"w":"vascular","tr":"damarsal / damar ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the tubes that carry blood or water","dt":"Kan veya su taşıyan tüplerle (damarlarla) ilgili","e1":"Vascular system.","e1t":"Damar sistemi.","e2":"Vascular plants.","e2t":"Damarlı bitkiler."},{"w":"vast","tr":"uçsuz bucaksız / devasa / çok büyük","te":"Adjective","tt":"Sıfat","de":"Extremely large","dt":"Son derece büyük","e1":"A vast area of forest.","e1t":"Uçsuz bucaksız bir orman alanı.","e2":"The vast majority of people.","e2t":"İnsanların büyük çoğunluğu."},{"w":"vault","tr":"tonoz / mahzen / kasa dairesi / atlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A room under a church used for burials; or a bank safe","dt":"Kilise altındaki mezar odası; veya banka kasası","e1":"Bank vault.","e1t":"Banka kasası (mahzeni).","e2":"Burial vault.","e2t":"Mezar odası."},{"w":"vegetation","tr":"bitki örtüsü / vejetasyon","te":"Noun","tt":"İsim","de":"Plants in general or the plants found in a particular area","dt":"Genel olarak bitkiler veya belirli bir alandaki bitkiler","e1":"Lush tropical vegetation.","e1t":"Gür tropikal bitki örtüsü.","e2":"Lack of vegetation.","e2t":"Bitki örtüsü eksikliği."},{"w":"vehicle","tr":"araç / vasıta / taşıt","te":"Noun","tt":"İsim","de":"A machine with an engine used for carrying people or goods","dt":"İnsan veya mal taşımak için kullanılan motorlu makine","e1":"Motor vehicle.","e1t":"Motorlu taşıt.","e2":"The movie was a vehicle for his talent.","e2t":"Film, onun yeteneğini sergilemesi için bir araçtı."},{"w":"veil","tr":"duvak / peçe / örtü / gizlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of thin material worn by women to cover the face","dt":"Kadınların yüzlerini örtmek için taktığı ince kumaş parçası","e1":"A bridal veil.","e1t":"Gelin duvağı.","e2":"A veil of secrecy.","e2t":"Gizlilik örtüsü."},{"w":"vein","tr":"damar / tarz / üslup / ruh hali","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tube that carries blood to the heart; or a layer of metal","dt":"Kanı kalbe taşıyan tüp; veya metal tabakası","e1":"To bleed from a vein.","e1t":"Bir damardan kanamak.","e2":"A vein of humor in the book.","e2t":"Kitaptaki bir mizah damarı (tarzı)."},{"w":"velocity","tr":"hız / sürat","te":"Noun","tt":"İsim","de":"The speed of something that is moving in a particular direction","dt":"Belirli bir yönde hareket eden bir şeyin hızı","e1":"The velocity of light.","e1t":"Işığın hızı.","e2":"Escape velocity.","e2t":"Kaçış hızı."},{"w":"velvet","tr":"kadife / kadifemsi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A cloth with a thick soft surface on one side","dt":"Bir tarafı kalın yumuşak yüzeyli kumaş","e1":"A velvet dress.","e1t":"Kadife elbise.","e2":"Soft as velvet.","e2t":"Kadife gibi yumuşak."},{"w":"vendor","tr":"satıcı / bayi / iş ortağı","te":"Noun","tt":"İsim","de":"A person or company that sells something","dt":"Bir şey satan kişi veya şirket","e1":"Street vendor.","e1t":"Sokak satıcısı (işportacı).","e2":"Software vendor.","e2t":"Yazılım tedarikçisi (satıcısı)."},{"w":"venerable","tr":"saygın / muhterem / kutsal (kişi)","te":"Adjective","tt":"Sıfat","de":"Deserving respect because of age, wisdom, or character","dt":"Yaşı, bilgeliği veya karakteri nedeniyle saygıyı hak eden","e1":"A venerable old man.","e1t":"Saygın (muhterem) yaşlı bir adam.","e2":"A venerable institution.","e2t":"Köklü (saygın) bir kurum."},{"w":"vent","tr":"havalandırma deliği / dışa vurmak / delik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A hole that allows air or gas to escape; or to express anger","dt":"Hava veya gazın çıkmasını sağlayan delik; veya öfke kusmak","e1":"Air vent.","e1t":"Havalandırma deliği.","e2":"To give vent to your frustration.","e2t":"Hayal kırıklığını dışa vurmak (boşaltmak)."},{"w":"ventilate","tr":"havalandırmak / dışa vurmak","te":"Verb","tt":"Fiil","de":"To cause fresh air to enter and move around a closed space","dt":"Kapalı bir alana taze hava girmesini ve dolaşmasını sağlamak","e1":"We need to ventilate the room.","e1t":"Odayı havalandırmamız gerekiyor.","e2":"To ventilate your grievances (to express them).","e2t":"Şikayetlerini dile getirmek (dışa vurmak)."},{"w":"ventilation","tr":"havalandırma","te":"Noun","tt":"İsim","de":"The movement of fresh air around a room or building","dt":"Bir oda veya bina içindeki taze hava hareketi","e1":"Poor ventilation leads to dampness.","e1t":"Kötü havalandırma rutubete neden olur.","e2":"Ventilation system.","e2t":"Havalandırma sistemi."},{"w":"venture","tr":"girişim / risk / cüret etmek / göze almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A new activity or business that involves risk","dt":"Risk içeren yeni faaliyet veya iş","e1":"A joint venture.","e1t":"Ortak girişim.","e2":"Nothing ventured, nothing gained.","e2t":"Risk almayan kazanamaz."},{"w":"verdict","tr":"hüküm / karar / yargı","te":"Noun","tt":"İsim","de":"An official decision made in a court of law","dt":"Mahkemede verilen resmi karar","e1":"The jury reached a verdict of not guilty.","e1t":"Jüri suçsuzluk kararına vardı.","e2":"What's your verdict on the new movie?","e2t":"Yeni film hakkındaki hükmün (kararın) nedir?"},{"w":"verge","tr":"eşik / kenar / sınır /","te":"e çok yaklaşmak","tt":"Noun/Verb","de":"İsim/Fiil","dt":"The edge or border of something; or to be very close to","e1":"Bir şeyin kenarı veya sınırı; veya bir şeye çok yakın olmak","e1t":"On the verge of collapse.","e2":"Çökmenin eşiğinde.","e2t":"Grass verge (at the side of a road)."},{"w":"verify","tr":"doğrulamak / teyit etmek / kanıtlamak","te":"Verb","tt":"Fiil","de":"To prove that something is true or correct","dt":"Bir şeyin doğru veya gerçek olduğunu kanıtlamak","e1":"Please verify your email address.","e1t":"Lütfen e","e2":"posta adresinizi doğrulayın.","e2t":"To verify a theory."},{"w":"versatile","tr":"çok yönlü / marifetli / elinden her iş gelen","te":"Adjective","tt":"Sıfat","de":"Able to be used for many different purposes","dt":"Birçok farklı amaç için kullanılabilen","e1":"A versatile tool.","e1t":"Çok yönlü bir alet.","e2":"He is a very versatile actor.","e2t":"O çok yönlü bir aktördür."},{"w":"versatility","tr":"çok yönlülük / marifet","te":"Noun","tt":"İsim","de":"The quality of being able to do many different things","dt":"Birçok farklı şeyi yapabilme niteliği","e1":"The versatility of the smartphone.","e1t":"Akıllı telefonun çok yönlülüğü.","e2":"To demonstrate great versatility.","e2t":"Büyük bir marifet (çok yönlülük) sergilemek."},{"w":"verse","tr":"dize / mısra / ayet / şiir","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of writing in a poem; or a part of a holy book","dt":"Şiirdeki yazı satırı; veya kutsal kitabın bir bölümü","e1":"To write in verse.","e1t":"Şiirsel (manzum) yazmak.","e2":"Chapter and verse.","e2t":"Tüm detaylarıyla (fasıl ve ayet)."},{"w":"version","tr":"versiyon / sürüm / yorum / anlatım","te":"Noun/Verb","tt":"İsim/Fiil","de":"A particular form of something that is slightly different","dt":"Bir şeyin biraz farklı olan belirli formu","e1":"The latest version of the software.","e1t":"Yazılımın en son sürümü.","e2":"His version of events.","e2t":"Olayları onun anlatış biçimi (yorumu)."},{"w":"vertical","tr":"dikey / dik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Standing or pointing straight up or down","dt":"Dosdoğru yukarı veya aşağı duran/işaret eden","e1":"A vertical line.","e1t":"Dikey bir çizgi.","e2":"Vertical integration.","e2t":"Dikey entegrasyon."},{"w":"vessel","tr":"gemi / damar / kap / kase","te":"Noun","tt":"İsim","de":"A large boat or ship; or a container; or a tube for blood","dt":"Büyük tekne veya gemi; veya kap; veya kan taşıyan tüp","e1":"A fishing vessel.","e1t":"Balıkçı gemisi.","e2":"Blood vessels.","e2t":"Kan damarları."},{"w":"vest","tr":"yelek / atlet / yetki vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of clothing with no sleeves; or to give power","dt":"Kolsuz giysi; veya güç/yetki vermek","e1":"Bulletproof vest.","e1t":"Kurşun geçirmez yelek.","e2":"To vest authority in someone.","e2t":"Birine yetki vermek."},{"w":"veto","tr":"veto / veto etmek / reddetmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official power to stop a decision","dt":"Bir kararı durdurma resmi gücü","e1":"To exercise your right of veto.","e1t":"Veto hakkını kullanmak.","e2":"The president vetoed the bill.","e2t":"Başkan yasa tasarısını veto etti."},{"w":"vex","tr":"canını sıkmak / kızdırmak / üzmek","te":"Verb","tt":"Fiil","de":"To cause someone to feel annoyed or worried","dt":"Birinin sinirlenmesine veya endişelenmesine neden olmak","e1":"It vexes me to see so much waste.","e1t":"Bu kadar israfı görmek canımı sıkıyor.","e2":"A vexing problem.","e2t":"Sinir bozucu (çözümsüz) bir sorun."},{"w":"via","tr":"aracılığıyla / vasıtasıyla / üzerinden","te":"Preposition","tt":"Edat","de":"Going through a place; or using a particular method","dt":"Bir yerin içinden geçerek; veya belirli bir yöntemi kullanarak","e1":"I sent the files via email.","e1t":"Dosyaları e","e2":"posta aracılığıyla gönderdim.","e2t":"To fly to New York via London."},{"w":"viable","tr":"uygulanabilir / yaşayabilir / kârlı","te":"Adjective","tt":"Sıfat","de":"Able to work as intended or able to succeed","dt":"Amaçlandığı gibi çalışabilen veya başarılı olabilen","e1":"A viable business plan.","e1t":"Uygulanabilir (yürütülebilir) bir iş planı.","e2":"Is the project economically viable?","e2t":"Proje ekonomik olarak kârlı mı?"},{"w":"vibrate","tr":"titremek / titreşmek","te":"Verb","tt":"Fiil","de":"To shake continuously with small fast movements","dt":"Küçük hızlı hareketlerle sürekli sallanmak","e1":"Your phone is vibrating.","e1t":"Telefonun titriyor.","e2":"The house vibrates when a truck passes.","e2t":"Kamyon geçtiğinde ev sarsılıyor (titriyor)."},{"w":"vibration","tr":"titreşim / sarsıntı","te":"Noun","tt":"İsim","de":"A continuous shaking movement","dt":"Sürekli sallanma hareketi","e1":"To feel the vibrations.","e1t":"Titreşimleri hissetmek.","e2":"Sound is caused by vibration.","e2t":"Ses titreşimden kaynaklanır."},{"w":"vicinity","tr":"civar / çevre / yakınlık","te":"Noun","tt":"İsim","de":"The area around a place","dt":"Bir yerin etrafındaki alan","e1":"In the vicinity of the hospital.","e1t":"Hastanenin civarında.","e2":"There is no school in the immediate vicinity.","e2t":"Yakın çevrede hiç okul yok."},{"w":"vicious","tr":"ahlaksız / vahşi / gaddar / şiddetli","te":"Adjective","tt":"Sıfat","de":"Cruel, violent, or dangerous","dt":"Zalim, şiddetli veya tehlikeli","e1":"A vicious dog.","e1t":"Saldırgan (vahşi) bir köpek.","e2":"A vicious circle.","e2t":"Kısır döngü."},{"w":"victim","tr":"kurban / mağdur","te":"Noun","tt":"İsim","de":"A person who has been hurt or killed","dt":"Zarar görmüş veya öldürülmüş kişi","e1":"The victims of the earthquake.","e1t":"Deprem mağdurları.","e2":"Crime victim.","e2t":"Suç mağduru."},{"w":"victorious","tr":"galip / muzaffer","te":"Adjective","tt":"Sıfat","de":"Having won a victory","dt":"Zafer kazanmış","e1":"The victorious army.","e1t":"Muzaffer (galip) ordu.","e2":"To emerge victorious.","e2t":"Galip çıkmak."},{"w":"victory","tr":"zafer / galibiyet","te":"Noun","tt":"İsim","de":"A success in a war, game, or competition","dt":"Savaşta, oyunda veya yarışmada başarı","e1":"To win a decisive victory.","e1t":"Kesin bir zafer kazanmak.","e2":"Election victory.","e2t":"Seçim galibiyeti."},{"w":"viewpoint","tr":"bakış açısı / görüş noktası","te":"Noun","tt":"İsim","de":"A place from which something can be seen; or an opinion","dt":"Bir şeyin görülebileceği yer; veya görüş","e1":"From a historical viewpoint.","e1t":"Tarihsel bir bakış açısıyla.","e2":"A popular viewpoint.","e2t":"Yaygın bir görüş."},{"w":"vigor / vigour","tr":"enerji / güç / dinçlik / gayret","te":"Noun","tt":"İsim","de":"Strength, energy, or enthusiasm","dt":"Güç, enerji veya heves","e1":"To work with great vigor.","e1t":"Büyük bir gayretle (şevkle) çalışmak.","e2":"Full of vigor.","e2t":"Enerji dolu."},{"w":"vigorous","tr":"enerjik / güçlü / zinde / şiddetli","te":"Adjective","tt":"Sıfat","de":"Using a lot of energy or strength","dt":"Çok fazla enerji veya güç kullanan","e1":"Vigorous exercise.","e1t":"Ağır (enerjik) egzersiz.","e2":"A vigorous defense of his ideas.","e2t":"Fikirlerinin güçlü bir şekilde savunulması."},{"w":"villa","tr":"villa / yazlık","te":"Noun","tt":"İsim","de":"A large house with a garden, usually for holidays","dt":"Genellikle tatil için, bahçeli büyük ev","e1":"To rent a villa for the summer.","e1t":"Yaz için bir villa kiralamak.","e2":"Roman villa.","e2t":"Roma villası."},{"w":"village","tr":"köy","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very small town in the countryside","dt":"Kırsal alandaki çok küçük yerleşim yeri","e1":"A mountain village.","e1t":"Dağ köyü.","e2":"To live in a village.","e2t":"Köyde yaşamak."},{"w":"vine","tr":"sarmaşık / asma","te":"Noun","tt":"İsim","de":"A plant that grows up or over things; or the plant grapes grow on","dt":"Şeylerin üzerine tırmanan bitki; veya üzümün yetiştiği bitki","e1":"Grape vines.","e1t":"Üzüm asmaları.","e2":"The vine climbed the wall.","e2t":"Sarmaşık duvara tırmandı."},{"w":"vinegar","tr":"sirke","te":"Noun","tt":"İsim","de":"A sour liquid used in cooking","dt":"Yemeklerde kullanılan ekşi sıvı","e1":"Apple cider vinegar.","e1t":"Elma sirkesi.","e2":"Oil and vinegar.","e2t":"Yağ ve sirke."},{"w":"vineyard","tr":"üzüm bağı","te":"Noun","tt":"İsim","de":"A piece of land where grapes are grown for making wine","dt":"Şarap yapmak için üzüm yetiştirilen arazi","e1":"To visit a vineyard.","e1t":"Üzüm bağını ziyaret etmek.","e2":"Vineyard owner.","e2t":"Bağ sahibi."},{"w":"vintage","tr":"bağ bozumu / klasik / eski ve kaliteli / seçkin","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"High quality from the past; or the year wine was made","dt":"Geçmişten gelen yüksek kalite; veya şarabın yapıldığı yıl","e1":"Vintage cars.","e1t":"Klasik (antika) arabalar.","e2":"A vintage year for Bordeaux wine.","e2t":"Bordeaux şarabı için iyi bir bağ bozumu yılı."},{"w":"violate","tr":"ihlal etmek / çiğnemek / tecavüz etmek","te":"Verb","tt":"Fiil","de":"To break a law or a promise; or to treat without respect","dt":"Bir yasayı veya sözü bozmak; veya saygısızca davranmak","e1":"To violate human rights.","e1t":"İnsan haklarını ihlal etmek.","e2":"To violate a treaty.","e2t":"Bir antlaşmayı çiğnemek."},{"w":"violation","tr":"ihlal / ihlal etme","te":"Noun","tt":"İsim","de":"An action that breaks a law, agreement, or principle","dt":"Yasayı, anlaşmayı veya ilkeyi bozan eylem","e1":"A violation of international law.","e1t":"Uluslararası hukukun ihlali.","e2":"Traffic violation.","e2t":"Trafik kuralı ihlali."},{"w":"violence","tr":"şiddet / zorbalık","te":"Noun","tt":"İsim","de":"Actions or words that are intended to hurt people","dt":"İnsanları incitmeyi amaçlayan eylemler veya sözler","e1":"Domestic violence.","e1t":"Aile içi şiddet.","e2":"To use violence to get what you want.","e2t":"İstediğini elde etmek için şiddet kullanmak."},{"w":"violent","tr":"şiddetli / sert / saldırgan","te":"Adjective","tt":"Sıfat","de":"Using force to hurt or kill people","dt":"İnsanları incitmek veya öldürmek için güç kullanan","e1":"A violent crime.","e1t":"Şiddetli bir suç.","e2":"Violent weather.","e2t":"Sert (şiddetli) hava."},{"w":"violet","tr":"menekşe / menekşe rengi (mor)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A small plant with purple flowers; or a bluish","dt":"purple color","e1":"Mor çiçekli küçük bitki; veya mavimsi","e1t":"mor renk","e2":"Violets grow in the spring.","e2t":"Menekşeler baharda yetişir."},{"w":"violin","tr":"keman","te":"Noun","tt":"İsim","de":"A musical instrument with four strings played with a bow","dt":"Yayla çalınan dört telli müzik aleti","e1":"To play the violin.","e1t":"Keman çalmak.","e2":"First violin.","e2t":"Birinci keman."},{"w":"violinist","tr":"kemancı","te":"Noun","tt":"İsim","de":"A person who plays the violin","dt":"Keman çalan kişi","e1":"A world","e1t":"famous violinist.","e2":"Dünyaca ünlü bir kemancı.","e2t":"Classical violinist."},{"w":"virgin","tr":"bakire / dokunulmamış / el değmemiş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has never had sex; or in its original state","dt":"Hiç cinsel ilişkiye girmemiş kişi; veya orijinal durumunda","e1":"Virgin forest.","e1t":"El değmemiş orman.","e2":"Extra virgin olive oil.","e2t":"Sızma (ilk baskı) zeytinyağı."},{"w":"virtual","tr":"sanal / neredeyse / gerçek gibi","te":"Adjective","tt":"Sıfat","de":"Created by a computer; or almost the same as","dt":"Bilgisayar tarafından oluşturulan; veya neredeyse aynı olan","e1":"Virtual reality (VR).","e1t":"Sanal gerçeklik.","e2":"The project was a virtual failure (almost a failure).","e2t":"Proje neredeyse bir başarısızlıktı."},{"w":"virtually","tr":"neredeyse / hemen hemen / sanal olarak","te":"Adverb","tt":"Zarf","de":"Almost; or using a computer","dt":"Hemen hemen; veya bilgisayar kullanarak","e1":"Virtually everyone was there.","e1t":"Hemen hemen herkes oradaydı.","e2":"To meet virtually.","e2t":"Sanal ortamda buluşmak."},{"w":"virtue","tr":"erdem / üstünlük / meziyet / yarar","te":"Noun","tt":"İsim","de":"A good moral quality; or an advantage","dt":"İyi bir ahlaki nitelik; veya bir avantaj","e1":"Patience is a virtue.","e1t":"Sabır bir erdemdir.","e2":"To act with virtue.","e2t":"Erdemle hareket etmek."},{"w":"virus","tr":"virüs","te":"Noun","tt":"İsim","de":"A very small living thing that causes disease","dt":"Hastalığa neden olan çok küçük canlı","e1":"A computer virus.","e1t":"Bilgisayar virüsü.","e2":"To catch a virus.","e2t":"Virüs kapmak."},{"w":"visa","tr":"vize","te":"Noun/Verb","tt":"İsim/Fiil","de":"Official permission to enter a foreign country","dt":"Yabancı bir ülkeye girmek için resmi izin","e1":"To apply for a student visa.","e1t":"Öğrenci vizesine başvurmak.","e2":"Entry visa.","e2t":"Giriş vizesi."},{"w":"viscount","tr":"vikont","te":"Noun","tt":"İsim","de":"A British nobleman with a rank below an earl","dt":"Kontun altında bir rütbeye sahip İngiliz soylusu","e1":"The Viscount of...","e1t":"... Vikontu.","e2":"A noble title.","e2t":"Bir soyluluk unvanı."},{"w":"visible","tr":"görünür / gözle görülen","te":"Adjective","tt":"Sıfat","de":"Able to be seen","dt":"Görülebilen","e1":"The stars are visible tonight.","e1t":"Yıldızlar bu gece görünür durumda.","e2":"No visible sign of injury.","e2t":"Görünür bir yaralanma belirtisi yok."},{"w":"vision","tr":"vizyon / görme / hayal / öngörü","te":"Noun/Verb","tt":"İsim/Fiil","de":"The ability to see; or a mental picture of the future","dt":"Görme yeteneği; veya geleceğe dair zihinsel resim","e1":"He has poor vision.","e1t":"Görme yeteneği zayıf.","e2":"A leader with a vision.","e2t":"Vizyon sahibi bir lider."},{"w":"visit","tr":"ziyaret / ziyaret etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To go to see a person or a place","dt":"Bir kişiyi veya yeri görmeye gitmek","e1":"To visit a museum.","e1t":"Bir müzeyi ziyaret etmek.","e2":"To pay a visit.","e2t":"Ziyarette bulunmak."},{"w":"visual","tr":"görsel / görme ile ilgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to seeing or sight","dt":"Görme veya görüş ile ilgili","e1":"The movie has amazing visual effects.","e1t":"Filmin harika görsel efektleri var.","e2":"Visual aids for teaching.","e2t":"Öğretim için görsel araçlar."},{"w":"visualize / visualise","tr":"gözünde canlandırmak / hayal etmek","te":"Verb","tt":"Fiil","de":"To form a picture of someone or something in your mind","dt":"Zihninde birinin veya bir şeyin resmini oluşturmak","e1":"Try to visualize the finished building.","e1t":"Bitmiş binayı gözünde canlandırmaya çalış.","e2":"It's hard to visualize how it will look.","e2t":"Nasıl görüneceğini hayal etmek zor."},{"w":"vital","tr":"hayati / çok önemli / zinde","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Extremely important; or necessary for life","dt":"Son derece önemli; veya yaşam için gerekli","e1":"The heart is a vital organ.","e1t":"Kalp hayati bir organdır.","e2":"Speed is of vital importance.","e2t":"Hız hayati öneme sahiptir."},{"w":"vitamin","tr":"vitamin","te":"Noun","tt":"İsim","de":"A natural substance found in food that is necessary for health","dt":"Sağlık için gerekli olan, yiyeceklerde bulunan doğal madde","e1":"Fruits are rich in vitamins.","e1t":"Meyveler vitamin bakımından zengindir.","e2":"Vitamin C supplements.","e2t":"C vitamini takviyeleri."},{"w":"vivid","tr":"canlı / parlak / net","te":"Adjective","tt":"Sıfat","de":"(Of a memory or description) producing very clear pictures in the mind","dt":"(Anı veya betimleme için) zihinde çok net resimler oluşturan","e1":"A vivid dream.","e1t":"Canlı (net) bir rüya.","e2":"He gave a vivid account of his trip.","e2t":"Yolculuğunun canlı bir anlatımını yaptı."},{"w":"vocal","tr":"sesle ilgili / sözlü / görüşünü açıkça söyleyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the voice; or expressing opinions freely","dt":"Sesle ilgili; veya fikirlerini özgürce ifade eden","e1":"Vocal cords.","e1t":"Ses telleri.","e2":"He is a very vocal critic of the government.","e2t":"Hükümetin fikirlerini açıkça söyleyen (sesli) bir eleştirmenidir."},{"w":"vocation","tr":"meslek / iş / tanrısal çağrı","te":"Noun","tt":"İsim","de":"A type of work that you feel you are suited for","dt":"Kendinizi uygun hissettiğiniz bir iş türü","e1":"Teaching is more than a job; it's a vocation.","e1t":"Öğretmenlik bir işten daha fazlasıdır; o bir gönül işidir (meslektir).","e2":"To find one's true vocation.","e2t":"Gerçek mesleğini (amacını) bulmak."},{"w":"vocational","tr":"mesleki / meslek ile ilgili","te":"Adjective","tt":"Sıfat","de":"Providing skills and education that prepare you for a job","dt":"Sizi bir işe hazırlayan beceri ve eğitimi sağlayan","e1":"Vocational training.","e1t":"Mesleki eğitim.","e2":"A vocational school.","e2t":"Meslek okulu."},{"w":"vogue","tr":"moda / rağbet","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A fashion or general popularity","dt":"Moda veya genel popülerlik","e1":"Short hair is in vogue again.","e1t":"Kısa saç yine moda.","e2":"The current vogue for organic food.","e2t":"Organik gıdaya olan mevcut rağbet."},{"w":"void","tr":"boşluk / geçersiz / hükümsüz","te":"Noun/Adj/Verb","tt":"A large empty space; or not legally valid","de":"Büyük boş alan; veya yasal olarak geçersiz","dt":"The contract was declared null and void.","e1":"Sözleşme hükümsüz (geçersiz) ilan edildi.","e1t":"To fill a void in one's life.","e2":"Hayatındaki bir boşluğu doldurmak.","e2t":""},{"w":"volatile","tr":"uçucu / değişken / istikrarsız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Likely to change suddenly or explode","dt":"Aniden değişmesi veya patlaması muhtemel","e1":"A volatile political situation.","e1t":"İstikrarsız bir siyasi durum.","e2":"Volatile liquids like petrol.","e2t":"Benzin gibi uçucu sıvılar."},{"w":"volcano","tr":"volkan / yanardağ","te":"Noun","tt":"İsim","de":"A mountain with a large hole at the top through which lava comes out","dt":"Tepesinde lavların çıktığı büyük bir delik olan dağ","e1":"An active volcano.","e1t":"Aktif bir yanardağ.","e2":"To erupt (for a volcano).","e2t":"(Yanardağ için) püskürmek."},{"w":"volt","tr":"volt","te":"Noun","tt":"İsim","de":"A unit for measuring the force of an electric current","dt":"Elektrik akımının gücünü ölçmek için kullanılan birim","e1":"A 12","e1t":"volt battery.","e2":"12 voltluk bir pil.","e2t":"High voltage."},{"w":"voltage","tr":"voltaj / gerilim","te":"Noun","tt":"İsim","de":"The force of an electric current measured in volts","dt":"Volt cinsinden ölçülen elektrik akımı gücü","e1":"To measure the voltage.","e1t":"Voltajı ölçmek.","e2":"Fluctuations in voltage.","e2t":"Voltajdaki dalgalanmalar."},{"w":"volume","tr":"hacim / cilt (kitap) / ses seviyesi","te":"Noun","tt":"İsim","de":"The amount of space that something contains; or a book","dt":"Bir şeyin kapladığı alan miktarı; veya kitap","e1":"The volume of a cylinder.","e1t":"Bir silindirin hacmi.","e2":"Please turn down the volume.","e2t":"Lütfen sesi kısın (ses seviyesini düşürün)."},{"w":"voluntary","tr":"gönüllü / isteğe bağlı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Done or given because you want to, not because you are forced","dt":"Zorlandığınız için değil, istediğiniz için yapılan veya verilen","e1":"Voluntary work.","e1t":"Gönüllü çalışma.","e2":"A voluntary organization.","e2t":"Gönüllü kuruluş (STK)."},{"w":"volunteer","tr":"gönüllü / gönüllü olmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who does something without being paid","dt":"Ücret almadan bir şey yapan kişi","e1":"To work as a volunteer.","e1t":"Gönüllü olarak çalışmak.","e2":"I volunteered to help with the project.","e2t":"Projeye yardım etmek için gönüllü oldum."},{"w":"vomit","tr":"kusmak / kusmuk","te":"Verb/Noun","tt":"Fiil/İsim","de":"To empty the contents of the stomach through the mouth","dt":"Midenin içindekileri ağız yoluyla boşaltmak","e1":"He vomited after eating the bad fish.","e1t":"Bozuk balığı yedikten sonra kustu.","e2":"To feel like vomiting (nausea).","e2t":"Kusacak gibi hissetmek (mide bulantısı)."},{"w":"voter","tr":"seçmen","te":"Noun","tt":"İsim","de":"A person who has the right to vote in an election","dt":"Seçimde oy kullanma hakkı olan kişi","e1":"The voters will decide the future of the country.","e1t":"Ülkenin geleceğine seçmenler karar verecek.","e2":"Registered voters.","e2t":"Kayıtlı seçmenler."},{"w":"votive","tr":"adak / adanmış","te":"Adjective","tt":"Sıfat","de":"Given or done to fulfill a religious promise","dt":"Dini bir sözü yerine getirmek için verilen veya yapılan","e1":"Votive candles.","e1t":"Adak mumları.","e2":"A votive offering.","e2t":"Adak sunusu."},{"w":"vouch","tr":"kefil olmak / doğruluğunu onaylamak","te":"Verb","tt":"Fiil","de":"To say that you know from experience that something is true","dt":"Bir şeyin doğru olduğunu tecrübenizle bildiğinizi söylemek","e1":"I can vouch for his honesty.","e1t":"Onun dürüstlüğüne kefil olabilirim.","e2":"Can anyone vouch for your story?","e2t":"Hikayeni doğrulayabilecek biri var mı?"},{"w":"voucher","tr":"kupon / fiş / makbuz","te":"Noun","tt":"İsim","de":"A piece of paper that can be used instead of money to pay for something","dt":"Bir şey ödemek için para yerine kullanılabilen kağıt parçası","e1":"A gift voucher for a bookshop.","e1t":"Bir kitapçı için hediye çeki (kuponu).","e2":"Travel vouchers.","e2t":"Seyahat kuponları."},{"w":"vow","tr":"yemin / ant / yemin etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A serious promise","dt":"Ciddi bir söz (vaat)","e1":"To take a vow of silence.","e1t":"Sessizlik yemini etmek.","e2":"Marriage vows.","e2t":"Evlilik yeminleri."},{"w":"vowel","tr":"ünlü harf / sesli harf","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A speech sound such as a, e, i, o, u","dt":"a, e, i, o, u gibi konuşma sesi","e1":"English has five main vowels.","e1t":"İngilizcenin beş temel ünlü harfi vardır.","e2":"Vowel sounds.","e2t":"Ünlü sesler."},{"w":"voyage","tr":"deniz yolculuğu / sefer","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long journey, especially by ship","dt":"Özellikle gemiyle yapılan uzun yolculuk","e1":"Bon voyage!","e1t":"İyi yolculuklar!","e2":"Columbus's first voyage to America.","e2t":"Kolomb'un Amerika'ya ilk seferi."},{"w":"vulgar","tr":"kaba / adi / görgüsüz","te":"Adjective","tt":"Sıfat","de":"Not polite or behaving in a way that is socially correct","dt":"Nazik olmayan veya toplumsal olarak doğru davranmayan","e1":"Vulgar language (swearing).","e1t":"Küfürlü (kaba) dil.","e2":"A vulgar person.","e2t":"Görgüsüz (kaba) bir kişi."},{"w":"vulnerability","tr":"savunmasızlık / hassasiyet / zayıflık","te":"Noun","tt":"İsim","de":"The quality of being easily hurt or attacked","dt":"Kolayca incitilme veya saldırıya uğrama niteliği","e1":"The vulnerability of small children.","e1t":"Küçük çocukların savunmasızlığı.","e2":"Security vulnerability (in a computer).","e2t":"Güvenlik açığı (zayıflığı)."},{"w":"vulnerable","tr":"savunmasız / hassas / kırılgan","te":"Adjective","tt":"Sıfat","de":"Able to be easily physically or emotionally hurt","dt":"Fiziksel veya duygusal olarak kolayca incitilebilen","e1":"Old people are vulnerable to the cold.","e1t":"Yaşlılar soğuğa karşı hassastır (savunmasızdır).","e2":"To be in a vulnerable position.","e2t":"Savunmasız bir durumda olmak."},{"w":"vulture","tr":"akbaba / sömürücü","te":"Noun","tt":"İsim","de":"A large bird that eats dead animals; or a person who profits from others' trouble","dt":"Ölü hayvanları yiyen büyük kuş; veya başkasının zor durumundan kâr sağlayan kişi","e1":"Vultures circling in the sky.","e1t":"Gökyüzünde dönen akbabalar.","e2":"Corporate vultures.","e2t":"Şirket avcıları (sömürücüler)."},{"w":"wade","tr":"(suda/çamurda) yürümek / zorla ilerlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk through water that is not deep","dt":"Derin olmayan suyun içinde yürümek","e1":"We waded across the stream.","e1t":"Derenin içinden karşıya yürüdük (geçtik).","e2":"To wade through a boring book.","e2t":"Sıkıcı bir kitabı (zorla) okuyup bitirmek."},{"w":"wag","tr":"(kuyruk) sallamak / sallanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a dog) to move the tail from side to side","dt":"(Köpek için) kuyruğu iki yana hareket ettirmek","e1":"The dog wagged its tail.","e1t":"Köpek kuyruğunu salladı.","e2":"To wag a finger at someone (to warn).","e2t":"Birine (uyarı amaçlı) parmak sallamak."},{"w":"wage","tr":"ücret / maaş / (savaş vb.) yürütmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of money that is paid weekly to a worker","dt":"Bir işçiye haftalık olarak ödenen para miktarı","e1":"Minimum wage.","e1t":"Asgari ücret.","e2":"Hourly wage.","e2t":"Saatlik ücret."},{"w":"wagon / waggon","tr":"vagon / at arabası / yük arabası","te":"Noun","tt":"İsim","de":"A vehicle with four wheels used for carrying heavy loads","dt":"Ağır yük taşımak için kullanılan dört tekerlekli araç","e1":"A railway wagon.","e1t":"Demiryolu vagonu.","e2":"A pioneer wagon.","e2t":"Öncü (atlı) yük arabası."},{"w":"wail","tr":"feryat etmek / ağlamak (yüksek sesle) / feryat","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cry out loudly in sadness or pain","dt":"Üzüntü veya acıyla yüksek sesle ağlamak","e1":"The child wailed for his mother.","e1t":"Çocuk annesi için feryat etti.","e2":"The wail of a siren.","e2t":"Sirenin acı acı çalması (inlemesi)."},{"w":"waist","tr":"bel","te":"Noun","tt":"İsim","de":"The part of the body between the chest and the hips","dt":"Göğüs ve kalça arasındaki vücut bölgesi","e1":"She has a narrow waist.","e1t":"İnce bir beli var.","e2":"Waist measurement.","e2t":"Bel ölçüsü."},{"w":"waistcoat","tr":"yelek (UK)","te":"Noun","tt":"İsim","de":"A piece of clothing with no sleeves, worn over a shirt (UK)","dt":"Gömlek üzerine giyilen kolsuz kıyafet (İngiltere'de waistcoat, ABD'de vest denir)","e1":"A three","e1t":"piece suit includes a waistcoat.","e2":"Üç parçalı takım elbise bir yelek içerir.","e2t":"To wear a waistcoat."},{"w":"waiter / waitress","tr":"garson / kadın garson","te":"Noun","tt":"İsim","de":"A person who serves food and drink at tables in a restaurant","dt":"Restoranda masalara yemek ve içecek servis eden kişi","e1":"Ask the waiter for the bill.","e1t":"Garsona hesabı sor.","e2":"To work as a waitress.","e2t":"Garson olarak çalışmak."},{"w":"waive","tr":"feragat etmek / vazgeçmek / (ücreti) almamak","te":"Verb","tt":"Fiil","de":"To officially state that a rule or right can be ignored","dt":"Bir kural veya haktan resmi olarak vazgeçildiğini bildirmek","e1":"The bank agreed to waive the fee.","e1t":"Banka ücreti almamayı (vazgeçmeyi) kabul etti.","e2":"To waive one's rights.","e2t":"Haklarından feragat etmek."},{"w":"waiver","tr":"feragatname / vazgeçme belgesi","te":"Noun","tt":"İsim","de":"An official document that states a right has been given up","dt":"Bir haktan vazgeçildiğini belirten resmi belge","e1":"To sign a waiver.","e1t":"Feragatname imzalamak.","e2":"A fee waiver.","e2t":"Ücret muafiyeti."},{"w":"wake","tr":"uyanmak / uyandırmak / (geminin bıraktığı) iz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To stop sleeping; or the track left by a boat","dt":"Uyumayı bırakmak; veya teknenin arkasında bıraktığı iz","e1":"Wake up!","e1t":"Uyan!","e2":"In the wake of the disaster (following).","e2t":"Felaketin peşinden (ardından)."},{"w":"walnut","tr":"ceviz / ceviz ağacı","te":"Noun","tt":"İsim","de":"A nut with a hard shell that looks like a brain","dt":"Beyne benzeyen sert kabuklu kuruyemiş","e1":"To crack a walnut.","e1t":"Ceviz kırmak.","e2":"Walnut wood.","e2t":"Ceviz odunu (mobilya için)."},{"w":"wander","tr":"dolaşmak / gezinmek / sapmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk around slowly in a relaxed way","dt":"Rahat bir şekilde yavaşça etrafta dolaşmak","e1":"We wandered through the old town.","e1t":"Eski şehirde dolaştık.","e2":"To wander from the subject.","e2t":"Konudan sapmak."},{"w":"wane","tr":"azalmak / zayıflamak / (ay) küçülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become weaker or less important","dt":"Daha zayıf veya daha az önemli hale gelmek","e1":"Her influence is starting to wane.","e1t":"Etkisi azalmaya başlıyor.","e2":"The waxing and waning of the moon.","e2t":"Ay'ın büyümesi ve küçülmesi."},{"w":"ward","tr":"koğuş / vesayet altındaki kişi / bölge / savuşturmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A room in a hospital; or a person under protection","dt":"Hastane odası (koğuş); veya koruma altındaki kişi","e1":"Maternity ward.","e1t":"Doğum koğuşu.","e2":"To be a ward of court.","e2t":"Mahkeme vesayeti altında olmak."},{"w":"warden","tr":"gardiyan / korucu / yönetici","te":"Noun","tt":"İsim","de":"A person who is in charge of a place or people","dt":"Bir yerin veya insanların başındaki görevli","e1":"Prison warden.","e1t":"Hapishane müdürü (gardiyanı).","e2":"Traffic warden.","e2t":"Trafik görevlisi."},{"w":"wardrobe","tr":"gardırop / gardırop dolabı / giysi koleksiyonu","te":"Noun","tt":"İsim","de":"A large cupboard for hanging clothes","dt":"Kıyafet asmak için kullanılan büyük dolap","e1":"To hang your coat in the wardrobe.","e1t":"Ceketini gardıroba asmak.","e2":"A summer wardrobe.","e2t":"Yazlık kıyafetler (koleksiyonu)."},{"w":"warehouse","tr":"depo / ambar","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large building for storing goods before they are sold","dt":"Malların satılmadan önce saklandığı büyük bina","e1":"Goods are stored in a warehouse.","e1t":"Mallar bir depoda saklanır.","e2":"Warehouse manager.","e2t":"Depo müdürü."},{"w":"warfare","tr":"savaş / savaşma","te":"Noun","tt":"İsim","de":"The activity of fighting a war","dt":"Savaş yapma faaliyeti","e1":"Guerrilla warfare.","e1t":"Gerilla savaşı.","e2":"Modern warfare.","e2t":"Modern savaş."},{"w":"warrant","tr":"garanti / arama emri / gerekçe / haklı çıkarmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official document; or a reason for doing something","dt":"Resmi belge; veya bir şeyi yapmak için neden/gerekçe","e1":"The police had a search warrant.","e1t":"Polisin arama emri vardı.","e2":"His behavior doesn't warrant such a reaction.","e2t":"Davranışı böyle bir tepkiyi haklı çıkarmaz (gerektirmez)."},{"w":"warrior","tr":"savaşçı / cengaver","te":"Noun","tt":"İsim","de":"A person who has experience and skill in fighting","dt":"Savaşma konusunda deneyim ve becerisi olan kişi","e1":"A brave warrior.","e1t":"Cesur bir savaşçı.","e2":"Warrior culture.","e2t":"Savaşçı kültürü."},{"w":"wary","tr":"temkinli / tedbirli / şüpheci","te":"Adjective","tt":"Sıfat","de":"Careful because you do not trust someone or something","dt":"Birine veya bir şeye güvenmediğiniz için dikkatli (temkinli)","e1":"To be wary of strangers.","e1t":"Yabancılara karşı temkinli olmak.","e2":"She gave him a wary look.","e2t":"Ona şüpheci (temkinli) bir bakış attı."},{"w":"washout","tr":"fiyasko / tam başarısızlık / (yerin) suyla aşınması","te":"Noun","tt":"İsim","de":"A complete failure; or a social event spoiled by rain","dt":"Tam bir başarısızlık; veya yağmur nedeniyle mahvolan etkinlik","e1":"The party was a total washout.","e1t":"Parti tam bir fiyaskoydu.","e2":"The road was closed due to a washout.","e2t":"Yol, su aşınması (toprak kayması) nedeniyle kapatıldı."},{"w":"wasp","tr":"eşek arısı","te":"Noun","tt":"İsim","de":"A black and yellow flying insect that can sting","dt":"Sokabilen, siyah ve sarı uçan böcek","e1":"I was stung by a wasp.","e1t":"Beni bir eşek arısı soktu.","e2":"A wasps' nest.","e2t":"Eşek arısı yuvası."},{"w":"waste","tr":"israf etmek / atık / çöp / ıssız","te":"Verb/Noun/Adj","tt":"To use more of something than is necessary; or useless materials","de":"Bir şeyi gereğinden fazla kullanmak (israf etmek); veya işe yaramaz maddeler","dt":"Don't waste your time.","e1":"Zamanını boşa harcama.","e1t":"Toxic waste.","e2":"Zehirli atık.","e2t":""},{"w":"watchful","tr":"dikkatli / uyanık / gözü açık","te":"Adjective","tt":"Sıfat","de":"Paying careful attention to what is happening","dt":"Neler olduğuna dikkatle odaklanan","e1":"Under the watchful eye of the teacher.","e1t":"Öğretmenin gözetimi (dikkatli bakışları) altında.","e2":"To keep a watchful eye on something.","e2t":"Bir şeyi dikkatle izlemek."},{"w":"waterproof","tr":"su geçirmez","te":"Adjective/Verb/Noun","tt":"Not allowing water to go through","de":"Suyun geçmesine izin vermeyen","dt":"A waterproof jacket.","e1":"Su geçirmez ceket.","e1t":"To waterproof a tent.","e2":"Bir çadırı su geçirmez hale getirmek.","e2t":""},{"w":"watertight","tr":"su sızdırmaz / tartışılmaz / kesin","te":"Adjective","tt":"Sıfat","de":"Not allowing water to get in; or (of a plan) having no faults","dt":"Su girmesine izin vermeyen; veya (plan için) hatasız/kesin","e1":"A watertight container.","e1t":"Su sızdırmaz kap.","e2":"A watertight alibi.","e2t":"Tartışılmaz (bozulamaz) bir mazeret."},{"w":"watt","tr":"vat","te":"Noun","tt":"İsim","de":"A unit for measuring electrical power","dt":"Elektrik gücünü ölçmek için kullanılan birim","e1":"A 60","e1t":"watt light bulb.","e2":"60 vatlık bir ampul.","e2t":"Kilowatt."},{"w":"wave","tr":"dalga / el sallamak / dalgalanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A movement of water; or to move your hand","dt":"Su hareketi; veya el sallamak","e1":"To wave goodbye.","e1t":"El sallayarak veda etmek.","e2":"Sound waves.","e2t":"Ses dalgaları."},{"w":"wavelength","tr":"dalga boyu / aynı frekansta (fikirsel)","te":"Noun","tt":"İsim","de":"The distance between two waves of light or sound","dt":"İki ışık veya ses dalgası arasındaki mesafe","e1":"To be on the same wavelength (to think in a similar way).","e1t":"Aynı dalga boyunda (frekansta) olmak.","e2":"Visible wavelengths.","e2t":"Görünür dalga boyları."},{"w":"waver","tr":"tereddüt etmek / sendelemek / dalgalanmak (ses/ışık)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To become weak or lose confidence","dt":"Zayıflamak veya güvenini kaybetmek","e1":"His voice wavered.","e1t":"Sesi titredi (dalgalandı).","e2":"To waver between two choices.","e2t":"İki seçenek arasında tereddüt etmek."},{"w":"wax","tr":"balmumu / ağda / (ay) büyümek / cilalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A solid substance that melts easily","dt":"Kolayca eriyen katı madde","e1":"Ear wax.","e1t":"Kulak kiri.","e2":"To wax a car.","e2t":"Arabayı cilalamak."},{"w":"wayward","tr":"dikbaşlı / başına buyruk / değişken","te":"Adjective","tt":"Sıfat","de":"Difficult to control or predict","dt":"Kontrol edilmesi veya tahmin edilmesi zor","e1":"A wayward child.","e1t":"Dikbaşlı (yaramaz) bir çocuk.","e2":"Wayward emotions.","e2t":"Değişken (kontrolsüz) duygular."},{"w":"weak","tr":"zayıf / güçsüz / halsiz","te":"Adjective","tt":"Sıfat","de":"Not strong; or easily broken","dt":"Güçlü olmayan; veya kolayca kırılan","e1":"To feel weak.","e1t":"Halsiz hissetmek.","e2":"A weak argument.","e2t":"Zayıf bir iddia."},{"w":"weaken","tr":"zayıflatmak / güçsüzleştirmek","te":"Verb","tt":"Fiil","de":"To become or make something less strong","dt":"Bir şeyi daha az güçlü hale getirmek veya gelmek","e1":"The fever weakened him.","e1t":"Ateş onu zayıf düşürdü.","e2":"To weaken someone's position.","e2t":"Birinin konumunu zayıflatmak."},{"w":"weakness","tr":"zayıflık / kusur / zaaf","te":"Noun","tt":"Isim","de":"The state of being weak; or a fault in someone's character","dt":"Zayıf olma durumu; veya birinin karakterindeki kusur (zaaf)","e1":"To have a weakness for chocolate.","e1t":"Çikolataya karşı zaafı olmak.","e2":"Strengths and weaknesses.","e2t":"Güçlü ve zayıf yönler."},{"w":"wealth","tr":"zenginlik / servet / bolluk","te":"Noun","tt":"İsim","de":"A large amount of money or valuable possessions","dt":"Büyük miktarda para veya değerli mülk","e1":"A wealth of information.","e1t":"Bilgi bolluğu (zenginliği).","e2":"To create wealth.","e2t":"Servet yaratmak."},{"w":"wealthy","tr":"zengin / varlıklı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Rich","dt":"Zengin","e1":"A wealthy businessman.","e1t":"Varlıklı bir iş adamı.","e2":"The wealthy (rich people).","e2t":"Zenginler."},{"w":"weapon","tr":"silah","te":"Noun/Verb","tt":"İsim/Fiil","de":"Any object used in fighting or war","dt":"Savaşta veya kavgada kullanılan herhangi bir nesne","e1":"Nuclear weapons.","e1t":"Nükleer silahlar.","e2":"A lethal weapon.","e2t":"Ölümcül bir silah."},{"w":"weary","tr":"yorgun / bitkin / usanmış / yormak","te":"Adjective/Verb","tt":"Very tired; or bored with something","de":"Çok yorgun; veya bir şeyden sıkılmış","dt":"To grow weary of the constant noise.","e1":"Sürekli gürültüden usanmak.","e1t":"A weary traveler.","e2":"Bitkin bir gezgin.","e2t":""},{"w":"weather","tr":"hava / atlatmak / aşınmak","te":"Noun/Verb/Adj","tt":"The conditions in the air outside; or to deal with a difficult situation","de":"Dışarıdaki hava koşulları; veya zor bir durumun üstesinden gelmek","dt":"Bad weather.","e1":"Kötü hava.","e1t":"To weather the storm (to survive a difficult time).","e2":"Fırtınayı atlatmak.","e2t":""},{"w":"weave","tr":"dokumak / örmek / zikzak çizmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make cloth by crossing threads; or to move in a complicated way","dt":"İplikleri çaprazlayarak kumaş yapmak; veya karmaşık şekilde ilerlemek","e1":"To weave a basket.","e1t":"Sepet örmek.","e2":"The spider wove a web.","e2t":"Örümcek bir ağ ördü."},{"w":"weaver","tr":"dokumacı","te":"Noun","tt":"İsim","de":"A person who weaves cloth","dt":"Kumaş dokuyan kişi","e1":"A traditional carpet weaver.","e1t":"Geleneksel halı dokumacısı.","e2":"Weaver bird.","e2t":"Dokumacı kuşu."},{"w":"wedge","tr":"kama / takoz / sıkıştırmak / dilim","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of wood or metal that is thick at one end","dt":"Bir ucu kalın olan ahşap veya metal parça","e1":"A wedge of cheese.","e1t":"Bir dilim peynir.","e2":"To wedge the door open.","e2t":"Kapıyı takozla açık tutmak."},{"w":"weed","tr":"yabani ot / otları temizlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A wild plant that you do not want in your garden","dt":"Bahçede istenmeyen yabani bitki","e1":"To pull up weeds.","e1t":"Yabani otları yolmak.","e2":"To weed the garden.","e2t":"Bahçeyi yabani otlardan temizlemek."},{"w":"weep","tr":"ağlamak (sessizce/derinden) / sızmak (yara)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cry, usually because of great sadness","dt":"Genellikle büyük bir üzüntü nedeniyle ağlamak","e1":"To weep for joy.","e1t":"Sevinçten ağlamak.","e2":"The wound began to weep (to leak liquid).","e2t":"Yara sızmaya (sıvı akıtmaya) başladı."},{"w":"weigh","tr":"tartmak / gelmek (ağırlık) / tartıp biçmek","te":"Verb","tt":"Fiil","de":"To measure how heavy someone or something is","dt":"Birinin veya bir şeyin ne kadar ağır olduğunu ölçmek","e1":"How much do you weigh?","e1t":"Kaç kilosun (ağırlığın ne)?","e2":"To weigh the pros and cons.","e2t":"Artıları ve eksileri tartıp biçmek."},{"w":"weight","tr":"ağırlık / yük / önem","te":"Noun/Verb","tt":"İsim/Fiil","de":"How heavy someone or something is","dt":"Birinin veya bir şeyin ne kadar ağır olduğu","e1":"To lose weight.","e1t":"Kilo vermek.","e2":"To gain weight.","e2t":"Kilo almak."},{"w":"weird","tr":"tuhaf / garip / acayip","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Very strange and unusual","dt":"Çok tuhaf ve sıra dışı","e1":"A weird noise.","e1t":"Garip bir gürültü.","e2":"That’s really weird.","e2t":"Bu gerçekten acayip."},{"w":"welcome","tr":"hoş geldin / karşılamak / memnuniyetle karşılamak","te":"Adj/Intj/Noun/Verb","tt":"Used to greet someone; or to be pleased about something","de":"Birini selamlamak için kullanılır; veya bir şeyden memnun olmak","dt":"You're welcome (as a response to thanks).","e1":"Rica ederim.","e1t":"To welcome a new idea.","e2":"Yeni bir fikri memnuniyetle karşılamak.","e2t":""},{"w":"welfare","tr":"refah / yardım / esenlik","te":"Noun","tt":"İsim","de":"Physical and mental health and happiness; or help given by the state","dt":"Fiziksel ve zihinsel sağlık ve mutluluk; veya devlet yardımı","e1":"Child welfare.","e1t":"Çocuk refahı (koruması).","e2":"Animal welfare.","e2t":"Hayvan hakları (refahı)."},{"w":"well","tr":"being","te":"esenlik / iyilik / refah","tt":"Noun","de":"İsim","dt":"The state of being healthy and happy","e1":"Sağlıklı ve mutlu olma durumu","e1t":"Emotional well","e2":"being.","e2t":"Duygusal esenlik."},{"w":"wharf","tr":"rıhtım / iskele","te":"Noun/Verb","tt":"İsim/Fiil","de":"A structure where ships are tied to load or unload goods","dt":"Gemilerin mal yüklemek veya boşaltmak için bağlandığı yapı","e1":"The ships were tied up at the wharf.","e1t":"Gemiler rıhtıma bağlanmıştı.","e2":"Fisherman's Wharf.","e2t":"Balıkçı Rıhtımı."},{"w":"whatsoever","tr":"hiçbir şekilde / asla / herhangi bir","te":"Adverb/Pronoun","tt":"Zarf/Zamir","de":"Used after a negative phrase to emphasize it","dt":"Vurgulamak için olumsuz bir ifadeden sonra kullanılır","e1":"I have no doubt whatsoever.","e1t":"Hiçbir şekilde şüphem yok (asla şüphe etmiyorum).","e2":"There is no evidence whatsoever.","e2t":"Herhangi bir kanıt yok."},{"w":"wheat","tr":"buğday","te":"Noun","tt":"İsim","de":"A plant whose grain is used for making flour","dt":"Taneleri un yapmak için kullanılan bitki","e1":"Wheat flour.","e1t":"Buğday unu.","e2":"A field of wheat.","e2t":"Buğday tarlası."},{"w":"wheel","tr":"tekerlek / direksiyon / çark / tekerlekli bir şeyle taşımak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A round object that turns to allow a vehicle to move","dt":"Bir aracın hareket etmesini sağlayan dönen yuvarlak nesne","e1":"Steering wheel.","e1t":"Direksiyon simidi.","e2":"To wheel a suitcase.","e2t":"Bir valizi tekerlekleri üzerinde sürmek."},{"w":"wheelchair","tr":"tekerlekli sandalye","te":"Noun","tt":"İsim","de":"A chair with wheels used by people who cannot walk","dt":"Yürüyemeyen insanların kullandığı tekerlekli sandalye","e1":"He is confined to a wheelchair.","e1t":"Tekerlekli sandalyeye mahkum.","e2":"Wheelchair access.","e2t":"Tekerlekli sandalye erişimi."},{"w":"whereabouts","tr":"bulunduğu yer / nerede","te":"Adverb/Noun","tt":"The place where someone or something is","de":"Birinin veya bir şeyin bulunduğu yer","dt":"His whereabouts are unknown.","e1":"Onun nerede olduğu bilinmiyor.","e1t":"Whereabouts do you live?","e2":"Tam olarak nerede yaşıyorsun?","e2t":""},{"w":"whereas","tr":"oysa / iken /","te":"e rağmen","tt":"Conjunction","de":"Bağlaç","dt":"Used to compare two things that are different","e1":"Farklı olan iki şeyi karşılaştırmak için kullanılır","e1t":"He likes meat, whereas she is a vegetarian.","e2":"O et sever, oysa o (kadın) bir vejetaryendir.","e2t":"Whereas in the past..."},{"w":"whereby","tr":"vasıtasıyla / sayesinde / uyarınca","te":"Adverb","tt":"Zarf","de":"By which way or method","dt":"Hangi yol veya yöntemle","e1":"A system whereby students can rate their teachers.","e1t":"Öğrencilerin öğretmenlerini değerlendirebildiği (vasıtasıyla değerlendirdiği) bir sistem.","e2":"The agreement whereby...","e2t":"... uyarınca yapılan anlaşma."},{"w":"whilst","tr":"iken / oysa (UK)","te":"Conjunction","tt":"Bağlaç","de":"During the time that something is happening (Same as \"while\")","dt":"Bir şeyin olduğu süre boyunca (while ile aynıdır, daha çok İngiltere'de kullanılır)","e1":"I heard the news whilst I was driving.","e1t":"Haberi araba sürerken duydum.","e2":"Whilst I agree with you, I still have concerns.","e2t":"Sana katılmakla birlikte (katılmama rağmen) hala endişelerim var."},{"w":"whip","tr":"kırbaç / kamçılamak / çırpmak (yumurta vb.) / hızla hareket etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long piece of leather used for hitting; or to mix quickly","dt":"Vurmak için kullanılan uzun deri parça; veya hızlıca karıştırmak","e1":"To whip cream.","e1t":"Krema çırpmak.","e2":"He whipped out his phone.","e2t":"Telefonunu hızla çıkardı."},{"w":"whirl","tr":"dönmek / döndürmek / girdap / başı dönmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To turn around in circles very quickly","dt":"Çok hızlı bir şekilde daireler çizerek dönmek","e1":"The leaves whirled in the wind.","e1t":"Yapraklar rüzgarda döndü (uçuştu).","e2":"My head is in a whirl.","e2t":"Başım dönüyor (zihnim karışık)."},{"w":"whisk","tr":"çırpmak (hızlıca) / hızla alıp götürmek / çırpma teli","te":"Verb/Noun","tt":"Fiil/İsim","de":"To mix something very quickly; or to move quickly","dt":"Bir şeyi çok hızlı karıştırmak; veya hızla hareket ettirmek","e1":"Whisk the eggs until they are fluffy.","e1t":"Yumurtaları kabarana kadar çırpın.","e2":"He was whisked away to the hospital.","e2t":"Hızla hastaneye götürüldü."},{"w":"whisper","tr":"fısıldamak / fısıltı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak very quietly so that other people cannot hear","dt":"Diğer insanların duyamayacağı şekilde çok sessiz konuşmak","e1":"She whispered a secret in my ear.","e1t":"Kulağıma bir sır fısıldadı.","e2":"To speak in a whisper.","e2t":"Fısıltıyla konuşmak."},{"w":"whistle","tr":"ıslık çalmak / düdük / ıslık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a high sound by blowing air through your lips","dt":"Dudakların arasından hava üfleyerek tiz bir ses çıkarmak","e1":"To whistle a tune.","e1t":"Bir melodiye ıslık çalmak.","e2":"The referee blew his whistle.","e2t":"Hakem düdüğünü çaldı."},{"w":"wholesome","tr":"sağlıklı / yararlı / iyicil","te":"Adjective","tt":"Sıfat","de":"Good for your health or moral character","dt":"Sağlığınız veya ahlaki karakteriniz için iyi olan","e1":"Wholesome food.","e1t":"Sağlıklı (doğal) gıda.","e2":"Wholesome family entertainment.","e2t":"Yararlı aile eğlencesi."},{"w":"wholly","tr":"tamamen / bütünüyle","te":"Adverb","tt":"Zarf","de":"Completely","dt":"Tamamen","e1":"I wholly agree with you.","e1t":"Sana tamamen katılıyorum.","e2":"Wholly inadequate.","e2t":"Tamamen yetersiz."},{"w":"wicked","tr":"kötü / günahkar / müthiş (argo)","te":"Adjective/Adv/Noun","tt":"Morally bad or evil; or very good (slang)","de":"Ahlaki olarak kötü veya fena; veya çok iyi (argo)","dt":"A wicked witch.","e1":"Kötü cadı.","e1t":"A wicked sense of humor.","e2":"Müthiş (zekice/şeytani) bir mizah anlayışı.","e2t":""},{"w":"wide","tr":"geniş / yaygın / uzak","te":"Adjective/Adverb/Noun","tt":"Measuring a large distance from one side to the other","de":"Bir taraftan diğerine büyük bir mesafeyi ölçen","dt":"A wide range of products.","e1":"Geniş bir ürün yelpazesi.","e1t":"With eyes wide open.","e2":"Gözleri fal taşı gibi açılmış.","e2t":""},{"w":"widen","tr":"genişletmek / açılmak / büyümek","te":"Verb","tt":"Fiil","de":"To become or make something wider","dt":"Genişlemek veya bir şeyi genişletmek","e1":"The road widens after the bridge.","e1t":"Köprüden sonra yol genişliyor.","e2":"To widen the gap between rich and poor.","e2t":"Zengin ve fakir arasındaki uçurumu açmak (genişletmek)."},{"w":"widespread","tr":"yaygın / geniş çaplı","te":"Adjective","tt":"Sıfat","de":"Existing or happening in many places","dt":"Birçok yerde var olan veya gerçekleşen","e1":"Widespread corruption.","e1t":"Yaygın yolsuzluk.","e2":"There is widespread support for the new law.","e2t":"Yeni yasaya yönelik geniş çaplı bir destek var."},{"w":"width","tr":"genişlik / en","te":"Noun","tt":"İsim","de":"The distance from one side of something to the other","dt":"Bir şeyin bir yanından diğer yanına olan mesafe","e1":"The width of the room is 5 meters.","e1t":"Odanın genişliği 5 metredir.","e2":"To measure the width.","e2t":"Genişliği ölçmek."},{"w":"wield","tr":"kullanmak (silah/güç) / sahip olmak","te":"Verb","tt":"Fiil","de":"To hold and use a tool or weapon; or to have power","dt":"Bir aleti veya silahı tutmak ve kullanmak; veya güce sahip olmak","e1":"To wield a sword.","e1t":"Kılıç kullanmak.","e2":"He wields a lot of influence in the company.","e2t":"Şirkette büyük bir nüfuz (güç) sahibi."},{"w":"wig","tr":"peruk","te":"Noun/Verb","tt":"İsim/Fiil","de":"A covering of artificial hair worn on the head","dt":"Başa takılan yapay saç","e1":"To wear a wig.","e1t":"Peruk takmak.","e2":"A barrister's wig.","e2t":"Avukat peruğu (İngiltere'de)."},{"w":"wildlife","tr":"yaban hayatı / yabani hayvanlar","te":"Noun","tt":"İsim","de":"Animals and plants growing in natural conditions","dt":"Doğal koşullarda yetişen hayvanlar ve bitkiler","e1":"To protect wildlife.","e1t":"Yaban hayatını korumak.","e2":"Wildlife documentary.","e2t":"Yaban hayatı belgeseli."},{"w":"willful / wilful","tr":"kasıtlı / inatçı / dikbaşlı","te":"Adjective","tt":"Sıfat","de":"Done on purpose; or determined to do what you want","dt":"Kasten yapılan; veya istediğini yapmaya kararlı (inatçı)","e1":"Willful damage.","e1t":"Kasıtlı zarar.","e2":"A willful child.","e2t":"İnatçı (dikbaşlı) bir çocuk."},{"w":"willing","tr":"istekli / gönüllü / hazır","te":"Adjective","tt":"Sıfat","de":"Ready or pleased to do something","dt":"Bir şeyi yapmaya hazır veya memnun","e1":"Are you willing to help us?","e1t":"Bize yardım etmeye istekli misin?","e2":"A willing volunteer.","e2t":"Gönüllü bir yardımcı."},{"w":"willingness","tr":"isteklilik / gönüllülük","te":"Noun","tt":"İsim","de":"The state of being happy to do something","dt":"Bir şeyi yapmaktan mutluluk duyma (istekli olma) durumu","e1":"To show a willingness to learn.","e1t":"Öğrenmeye isteklilik göstermek.","e2":"Her willingness to cooperate.","e2t":"Onun iş birliği yapma gönüllülüğü."},{"w":"willow","tr":"salkım söğüt / söğüt ağacı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A tree with long thin branches and narrow leaves","dt":"Uzun ince dalları ve dar yaprakları olan ağaç","e1":"Weeping willow.","e1t":"Salkım söğüt.","e2":"A cricket bat made of willow.","e2t":"Söğüt ağacından yapılmış kriket sopası."},{"w":"wind","tr":"rüzgâr / nefes / kurmak (saat vb.) / dolamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A current of air; or to turn something around","dt":"Hava akımı; veya bir şeyi döndürmek (kurmak/dolamak)","e1":"High winds.","e1t":"Güçlü rüzgârlar.","e2":"To wind a watch.","e2t":"Saat kurmak."},{"w":"windfall","tr":"beklenmedik kazanç / havadan gelen para / rüzgârın düşürdüğü meyve","te":"Noun","tt":"İsim","de":"An amount of money that you receive unexpectedly","dt":"Beklenmedik bir şekilde alınan para miktarı","e1":"A tax windfall.","e1t":"Beklenmedik vergi geliri.","e2":"To receive a windfall from an inheritance.","e2t":"Mirastan havadan gelen (beklenmedik) bir para almak."},{"w":"winding","tr":"dolambaçlı / kıvrımlı / kurma","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Following a curved or twisting path","dt":"Kavisli veya dolambaçlı bir yolu takip eden","e1":"A long winding road.","e1t":"Uzun dolambaçlı bir yol.","e2":"A winding staircase.","e2t":"Döner merdiven."},{"w":"windscreen / windshield","tr":"ön cam (araç)","te":"Noun","tt":"İsim","de":"The window at the front of a car or truck","dt":"Arabanın veya kamyonun önündeki cam","e1":"Windscreen wipers.","e1t":"Cam silecekleri.","e2":"A cracked windshield.","e2t":"Çatlak ön cam."},{"w":"windy","tr":"rüzgârlı","te":"Adjective","tt":"Sıfat","de":"With a lot of wind","dt":"Çok rüzgârlı","e1":"A windy day.","e1t":"Rüzgârlı bir gün.","e2":"Windy weather.","e2t":"Rüzgârlı hava."},{"w":"wink","tr":"göz kırpmak / göz kırpma","te":"Verb/Noun","tt":"Fiil/İsim","de":"To close one eye for a short time as a signal","dt":"İşaret olarak bir gözü kısa süreliğine kapatmak","e1":"He winked at me.","e1t":"Bana göz kırptı.","e2":"To not get a wink of sleep.","e2t":"Gözüne uyku girmemek."},{"w":"wipe","tr":"silmek / temizlemek / ıslak mendil","te":"Verb/Noun","tt":"Fiil/İsim","de":"To clean something by rubbing it with a cloth","dt":"Bir şeyi bezle ovarak temizlemek","e1":"Wipe your feet before you come in.","e1t":"İçeri girmeden önce ayaklarını sil.","e2":"To wipe out (to destroy completely).","e2t":"Yok etmek (kökünü kazımak)."},{"w":"wisdom","tr":"bilgelik / akıl / sağduyu","te":"Noun","tt":"İsim","de":"The ability to make good decisions based on experience","dt":"Deneyime dayalı iyi kararlar verme yeteneği","e1":"Words of wisdom.","e1t":"Bilgelik dolu sözler.","e2":"Conventional wisdom.","e2t":"Genel geçer (yaygın) kanı."},{"w":"wit","tr":"zeka / nükte / mizah anlayışı","te":"Noun","tt":"İsim","de":"The ability to say things that are clever and funny","dt":"Zekice ve komik şeyler söyleme yeteneği","e1":"A man of great wit.","e1t":"Çok nüktedan (zeki) bir adam.","e2":"To use your wits to survive.","e2t":"Hayatta kalmak için aklını kullanmak."},{"w":"witch","tr":"cadı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A woman who is thought to have magical powers","dt":"Büyülü güçleri olduğu düşünülen kadın","e1":"A wicked witch.","e1t":"Kötü bir cadı.","e2":"Witch hunt.","e2t":"Cadı avı."},{"w":"withdraw","tr":"geri çekmek / (para) çekmek / vazgeçmek","te":"Verb","tt":"Fiil","de":"To take something back or move away","dt":"Bir şeyi geri almak veya uzaklaşmak","e1":"To withdraw money from an ATM.","e1t":"ATM'den para çekmek.","e2":"To withdraw troops.","e2t":"Askerleri geri çekmek."},{"w":"withdrawal","tr":"geri çekilme / (para) çekme / yoksunluk","te":"Noun","tt":"İsim","de":"The act of taking something back; or the period after stopping a drug","dt":"Bir şeyi geri alma eylemi; veya bir ilacı bıraktıktan sonraki dönem","e1":"The withdrawal of support.","e1t":"Desteğin çekilmesi.","e2":"Withdrawal symptoms.","e2t":"Yoksunluk belirtileri (kriz)."},{"w":"wither","tr":"solmak / kurumak / zayıflamak","te":"Verb","tt":"Fiil","de":"(Of a plant) to become dry and die; or to become weaker","dt":"(Bitki için) kurumak ve ölmek; veya zayıflamak","e1":"The flowers withered in the sun.","e1t":"Çiçekler güneşte soldu.","e2":"His hopes withered away.","e2t":"Umutları tükendi (soldu)."},{"w":"withhold","tr":"vermemek / tutmak / saklamak","te":"Verb","tt":"Fiil","de":"To refuse to give something","dt":"Bir şeyi vermeyi reddetmek (elinde tutmak)","e1":"To withhold information from the police.","e1t":"Polisten bilgi saklamak.","e2":"Tax is withheld from your salary.","e2t":"Vergi maaşınızdan kesilir (tutulur)."},{"w":"within","tr":"içinde / dahilinde /","te":"den içeri","tt":"Preposition/Adverb","de":"Edat/Zarf","dt":"Inside a period of time, distance, or limit","e1":"Bir zaman, mesafe veya sınırın içinde","e1t":"Within walking distance.","e2":"Yürüme mesafesinde.","e2t":"Within 24 hours."},{"w":"withstand","tr":"dayanmak / karşı koymak / direnmek","te":"Verb","tt":"Fiil","de":"To be strong enough not to be harmed by something","dt":"Bir şeyden zarar görmeyecek kadar güçlü olmak","e1":"To withstand the pressure.","e1t":"Baskıya dayanmak.","e2":"These materials can withstand high temperatures.","e2t":"Bu malzemeler yüksek sıcaklıklara dayanabilir."},{"w":"witness","tr":"tanık / şahit / tanıklık etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who sees an event happen","dt":"Bir olayın gerçekleştiğini gören kişi","e1":"An eyewitness account.","e1t":"Görgü tanığı ifadesi.","e2":"To witness an accident.","e2t":"Bir kazaya tanık olmak."},{"w":"witty","tr":"nüktedan / zekice ve komik","te":"Adjective","tt":"Sıfat","de":"Using words in a clever and funny way","dt":"Kelimeleri zekice ve komik bir şekilde kullanan","e1":"A witty comment.","e1t":"Nükteli (zekice) bir yorum.","e2":"She is very witty.","e2t":"O çok nüktedandır."},{"w":"wizard","tr":"sihirbaz / büyücü / asistan (yazılım)","te":"Noun","tt":"İsim","de":"A man who has magical powers; or an expert","dt":"Büyülü güçleri olan adam; veya uzman","e1":"A computer wizard.","e1t":"Bilgisayar dehası (uzmanı).","e2":"Installation wizard.","e2t":"Kurulum sihirbazı."},{"w":"woe","tr":"keder / dert / felaket","te":"Noun/Intj","tt":"Great sadness; or serious problems","de":"Büyük üzüntü; veya ciddi sorunlar","dt":"Economic woes.","e1":"Ekonomik sıkıntılar (dertler).","e1t":"Woe is me!","e2":"Eyvahlar olsun bana!","e2t":""},{"w":"wolf","tr":"kurt / oburca yemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A wild animal of the dog family","dt":"Köpek ailesinden vahşi bir hayvan","e1":"A pack of wolves.","e1t":"Kurt sürüsü.","e2":"A lone wolf.","e2t":"Yalnız kurt."},{"w":"womb","tr":"rahim / döl yatağı","te":"Noun","tt":"İsim","de":"The organ in a woman's body where a baby grows","dt":"Kadın vücudunda bebeğin büyüdüğü organ","e1":"From the womb to the tomb.","e1t":"Beşikten mezara.","e2":"Inside the mother's womb.","e2t":"Anne karnında (rahimde)."},{"w":"wonder","tr":"merak etmek / mucize / hayret / harika","te":"Verb/Noun","tt":"Fiil/İsim","de":"To want to know something; or a feeling of surprise","dt":"Bir şeyi bilmek istemek; veya şaşkınlık hissi","e1":"I wonder why he is late.","e1t":"Neden geç kaldığını merak ediyorum.","e2":"The seven wonders of the world.","e2t":"Dünyanın yedi harikası."},{"w":"woodland","tr":"ormanlık alan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Land that is covered with trees","dt":"Ağaçlarla kaplı arazi","e1":"Ancient woodland.","e1t":"Kadim ormanlık alan.","e2":"Woodland birds.","e2t":"Orman kuşları."},{"w":"wool","tr":"yün / yünlü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The soft hair of sheep used for making cloth","dt":"Kumaş yapmak için kullanılan koyun tüyü","e1":"A sweater made of pure wool.","e1t":"Saf yünden yapılmış bir kazak.","e2":"Knitting wool.","e2t":"Örgü yünü."},{"w":"woolen / woollen","tr":"yünlü / yünden yapılmış","te":"Adjective","tt":"Sıfat","de":"Made of wool","dt":"Yünden yapılmış","e1":"Woolen blankets.","e1t":"Yünlü battaniyeler.","e2":"The woolen industry.","e2t":"Yünlü dokuma endüstrisi."},{"w":"wordy","tr":"laf kalabalığı yapan / çok kelimeli","te":"Adjective","tt":"Sıfat","de":"Using too many words","dt":"Çok fazla kelime kullanan","e1":"A wordy explanation.","e1t":"Çok uzun ve gereksiz (laf kalabalığı içeren) bir açıklama.","e2":"Wordy style.","e2t":"Ağdalı (kelime dolu) üslup."},{"w":"workshop","tr":"atölye / çalıştay","te":"Noun/Verb","tt":"İsim/Fiil","de":"A room where things are made; or a meeting for learning","dt":"Bir şeylerin yapıldığı oda; veya öğrenme amaçlı toplantı","e1":"A carpentry workshop.","e1t":"Marangoz atölyesi.","e2":"To attend a drama workshop.","e2t":"Drama çalıştayına katılmak."},{"w":"world","tr":"wide / worldwide","te":"dünya çapında / evrensel","tt":"Adjective/Adverb","de":"Sıfat/Zarf","dt":"Happening or existing in all parts of the world","e1":"Dünyanın her yerinde gerçekleşen veya var olan","e1t":"Worldwide fame.","e2":"Dünya çapında ün.","e2t":"To travel worldwide."},{"w":"worm","tr":"solucan / kurtçuk / yavaşça ilerlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small long thin creature with no bones","dt":"Kemiksiz, küçük, uzun ve ince canlı","e1":"Earthworm.","e1t":"Toprak solucanı.","e2":"Computer worm.","e2t":"Bilgisayar solucanı (virüsü)."},{"w":"worship","tr":"ibadet etmek / tapmak / ibadet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To show great respect for a god or a person","dt":"Bir tanrıya veya kişiye büyük saygı göstermek","e1":"To worship in a mosque.","e1t":"Camide ibadet etmek.","e2":"Hero worship.","e2t":"Kahramanlık hayranlığı (tapınma)."},{"w":"worth","tr":"değer /","te":"e değer / kıymet","tt":"Noun/Adjective","de":"İsim/Sıfat","dt":"The value of something; or used to say how much something costs","e1":"Bir şeyin değeri; veya bir şeyin ne kadar ettiğini söylemek için kullanılır","e1t":"How much is this ring worth?","e2":"Bu yüzük ne kadar eder (değeri ne)?","e2t":"It is worth a try."},{"w":"worthwhile","tr":"yapmaya değer / yararlı","te":"Adjective","tt":"Sıfat","de":"Useful or enjoyable enough to justify the time or money spent","dt":"Harcanan zamana veya paraya değecek kadar yararlı veya keyifli","e1":"A worthwhile career.","e1t":"Yapmaya değer (anlamlı) bir kariyer.","e2":"It's a worthwhile project.","e2t":"Yararlı (değerli) bir proje."},{"w":"worthy","tr":"layık / değer / saygın kişi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Deserving respect or attention","dt":"Saygı veya dikkati hak eden","e1":"To be worthy of praise.","e1t":"Övgüye layık olmak.","e2":"A worthy cause.","e2t":"Ulvi (değerli) bir amaç."},{"w":"wound","tr":"yara / yaralamak / incitmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A physical injury; or to hurt someone's feelings","dt":"Fiziksel yaralanma; veya birinin duygularını incitmek","e1":"A bullet wound.","e1t":"Kurşun yarası.","e2":"To wound someone's pride.","e2t":"Birinin gururunu incitmek."},{"w":"wrap","tr":"sarmak / paketlemek / sargı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cover something in paper or cloth","dt":"Bir şeyi kağıt veya kumaşla örtmek","e1":"To wrap a gift.","e1t":"Bir hediyeyi paketlemek.","e2":"Keep it under wraps (keep it secret).","e2t":"Gizli tut (sakla)."},{"w":"wrath","tr":"gazap / büyük öfke","te":"Noun","tt":"İsim","de":"Extreme anger (literary or formal)","dt":"Aşırı öfke (edebi veya resmi)","e1":"The wrath of God.","e1t":"Tanrı'nın gazabı.","e2":"To fear his father's wrath.","e2t":"Babasının gazabından korkmak."},{"w":"wreath","tr":"çelenk / halka","te":"Noun","tt":"İsim","de":"A circle of flowers or leaves used as a decoration or for a funeral","dt":"Dekorasyon veya cenaze için kullanılan çiçek veya yaprak halkası","e1":"To lay a wreath at the memorial.","e1t":"Anıta çelenk koymak.","e2":"Christmas wreath.","e2t":"Noel çelengi."},{"w":"wreck","tr":"enkaz / kaza / mahvetmek / batık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A car or ship that has been badly damaged; or to destroy","dt":"Ağır hasar görmüş araç veya gemi; veya mahvetmek","e1":"A nervous wreck (a very stressed person).","e1t":"Sinir küpü (bitkin halde).","e2":"The storm wrecked the house.","e2t":"Fırtına evi yerle bir etti (mahvetti)."},{"w":"wrench","tr":"ingiliz anahtarı / burkmak / söküp almak / acı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tool for turning nuts and bolts; or to pull suddenly","dt":"Somun ve cıvataları çevirmek için alet; veya aniden çekmek","e1":"To wrench your shoulder.","e1t":"Omuzunu burkmak (incitmek).","e2":"Leaving home was a real wrench (painful separation).","e2t":"Evden ayrılmak gerçek bir acıydı (yürek burkucuydu)."},{"w":"wrestle","tr":"güreşmek / çabalamak / mücadele etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fight someone by holding them and trying to throw them to the ground","dt":"Birini tutarak yere yıkmaya çalışmak (güreşmek); veya bir sorunla uğraşmak","e1":"To wrestle with a difficult problem.","e1t":"Zor bir problemle boğuşmak (mücadele etmek).","e2":"The two boys were wrestling on the grass.","e2t":"İki çocuk çimenlerin üzerinde güreşiyordu."},{"w":"wrestler","tr":"güreşçi","te":"Noun","tt":"İsim","de":"A person who takes part in the sport of wrestling","dt":"Güreş sporuna katılan kişi","e1":"A professional wrestler.","e1t":"Profesyonel güreşçi.","e2":"Olympic wrestler.","e2t":"Olimpiyat güreşçisi."},{"w":"wrestling","tr":"güreş","te":"Noun","tt":"İsim","de":"A sport in which two people wrestle","dt":"İki kişinin güreştiği spor","e1":"To watch wrestling on TV.","e1t":"Televizyonda güreş izlemek.","e2":"Greco","e2t":"Roman wrestling."},{"w":"wretched","tr":"perişan / zavallı / berbat / çok kötü","te":"Adjective","tt":"Sıfat","de":"Very unhappy or in a very bad situation","dt":"Çok mutsuz veya çok kötü bir durumda","e1":"I felt wretched after I heard the news.","e1t":"Haberi duyduktan sonra kendimi perişan hissettim.","e2":"Wretched living conditions.","e2t":"Berbat yaşam koşulları."},{"w":"wriggle","tr":"kıvranmak / kımıldamak / kurtulmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To twist your body with small quick movements","dt":"Vücudunu küçük hızlı hareketlerle bükmek (kıpırdanmak)","e1":"The baby wriggled in her arms.","e1t":"Bebek kollarında kıpırdandı (kıvrandı).","e2":"To wriggle out of a responsibility.","e2t":"Bir sorumluluktan (kıvırarak) kurtulmak."},{"w":"wrinkle","tr":"kırışıklık / buruşukluk / kırıştırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small line on your skin or on cloth","dt":"Deride veya kumaşta oluşan küçük çizgi","e1":"To have wrinkles around the eyes.","e1t":"Göz çevresinde kırışıklıklar olmak.","e2":"To wrinkle your forehead.","e2t":"Alnını kırıştırmak."},{"w":"wrist","tr":"bilek (el)","te":"Noun","tt":"İsim","de":"The part of the body between the hand and the arm","dt":"El ile kol arasındaki vücut bölümü","e1":"To wear a watch on your wrist.","e1t":"Bileğine saat takmak.","e2":"To sprain your wrist.","e2t":"Bileğini burkmak."},{"w":"writ","tr":"mahkeme emri / yazılı emir","te":"Noun","tt":"İsim","de":"A formal document from a court ordering someone to do something","dt":"Birine bir şey yapmasını emreden resmi mahkeme belgesi","e1":"To issue a writ.","e1t":"Mahkeme emri çıkarmak.","e2":"A writ of summons.","e2t":"Çağrı kağıdı (celp)."},{"w":"write","tr":"off","te":"hurda / kayıp / silinen borç","tt":"Noun","de":"İsim","dt":"A vehicle that is too badly damaged to be repaired; or a debt that will not be paid","e1":"Tamir edilemeyecek kadar hasarlı araç; veya ödenmeyecek olan borç","e1t":"The car was a total write","e2":"off after the crash.","e2t":"Kazadan sonra araba tam bir hurdaydı."},{"w":"wrongdoer","tr":"suçlu / günahkâr / hata yapan","te":"Noun","tt":"İsim","de":"A person who does something bad or illegal","dt":"Kötü veya yasadışı bir şey yapan kişi","e1":"To punish the wrongdoers.","e1t":"Suçluları cezalandırmak.","e2":"Moral wrongdoers.","e2t":"Günahkârlar (ahlaki hata yapanlar)."},{"w":"x","tr":"ray","te":"röntgen / X","tt":"ışını / röntgen çekmek","de":"Noun/Verb","dt":"İsim/Fiil","e1":"A photograph of the inside of the body using special rays","e1t":"Özel ışınlar kullanarak vücudun içini gösteren fotoğraf","e2":"To have an X","e2t":"ray of your chest."},{"w":"xerox","tr":"fotokopi çekmek / fotokopi makinesi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a copy of a document using a Xerox machine","dt":"Bir belgenin fotokopisini çekmek","e1":"Can you xerox these files for me?","e1t":"Bu dosyaların fotokopisini benim için çeker misin?","e2":"A xerox copy.","e2t":"Fotokopi."},{"w":"yacht","tr":"yat","te":"Noun/Verb","tt":"İsim/Fiil","de":"A boat with sails or an engine used for racing or pleasure","dt":"Yarış veya keyif için kullanılan yelkenli veya motorlu tekne","e1":"To go sailing on a yacht.","e1t":"Yatla denize açılmak.","e2":"Luxury yacht.","e2t":"Lüks yat."},{"w":"yard","tr":"bahçe / avlu / yarda (ölçü birimi)","te":"Noun","tt":"İsim","de":"An area of land next to a building; or a unit of length (0.91 meters)","dt":"Bina yanındaki arazi (bahçe); veya uzunluk birimi (yaklaşık 91 cm)","e1":"A back yard.","e1t":"Arka bahçe.","e2":"Yard by yard.","e2t":"Adım adım (yarda yarda)."},{"w":"yarn","tr":"iplik / yün / masal (uydurma)","te":"Noun/Verb","tt":"İsim/Fiil","de":"Thread used for knitting; or a long story that might not be true","dt":"Örgü için kullanılan ip; veya doğru olmayabilecek uzun hikaye","e1":"To spin a yarn (to tell a story).","e1t":"Hikaye (masal) anlatmak.","e2":"Woolen yarn.","e2t":"Yün iplik."},{"w":"yawn","tr":"esnemek / esneme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To open your mouth wide and breathe in deeply because you are tired","dt":"Yorgun olduğun için ağzını genişçe açıp derin nefes almak","e1":"To stifle a yawn.","e1t":"Esnemeyi bastırmak.","e2":"The giant hole yawned before us.","e2t":"Dev delik önümüzde (bir uçurum gibi) açılıyordu."},{"w":"yeast","tr":"maya","te":"Noun","tt":"İsim","de":"A substance used in making bread or beer to make it rise","dt":"Ekmek veya biranın kabarmasını sağlamak için kullanılan madde","e1":"To add yeast to the flour.","e1t":"Una maya eklemek.","e2":"Yeast infection.","e2t":"Mantar enfeksiyonu (maya kaynaklı)."},{"w":"yell","tr":"bağırmak / haykırmak / nida","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shout loudly, usually because you are angry or excited","dt":"Genellikle öfkeli veya heyecanlı olduğun için yüksek sesle bağırmak","e1":"To yell for help.","e1t":"Yardım için bağırmak.","e2":"Don't yell at me!","e2t":"Bana bağırma!"},{"w":"yellowish","tr":"sarımsı","te":"Adjective","tt":"Sıfat","de":"Slightly yellow in color","dt":"Rengi hafifçe sarı olan","e1":"Yellowish skin.","e1t":"Sarımsı ten.","e2":"A yellowish tint.","e2t":"Sarımsı bir ton."},{"w":"yelp","tr":"ciyaklamak / havlamak (acıyla)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To give a sudden short high cry of pain or excitement","dt":"Acı veya heyecanla ani, kısa ve tiz bir ses çıkarmak","e1":"The dog yelped when I stepped on its tail.","e1t":"Kuyruğuna bastığımda köpek ciyakladı.","e2":"A yelp of surprise.","e2t":"Bir şaşkınlık çığlığı."},{"w":"yield","tr":"ürün / verim / teslim olmak / yol vermek / sağlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount of something produced; or to produce; or to stop resisting","dt":"Üretilen miktar (verim); veya üretmek; veya direnmeyi bırakmak","e1":"High crop yields.","e1t":"Yüksek mahsul verimi.","e2":"To yield to pressure.","e2t":"Baskıya boyun eğmek."},{"w":"yoke","tr":"boyunduruk / boyunduruk altına almak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A wooden bar put around the necks of two animals; or lack of freedom","dt":"İki hayvanın boynuna takılan ahşap çubuk; veya özgürlük kısıtlaması","e1":"To live under the yoke of a tyrant.","e1t":"Bir diktatörün boyunduruğu altında yaşamak.","e2":"To yoke the oxen together.","e2t":"Öküzleri birbirine koşmak (boyunduruğa sokmak)."},{"w":"yolk","tr":"yumurta sarısı","te":"Noun","tt":"İsim","de":"The yellow middle part of an egg","dt":"Yumurtanın sarı orta kısmı","e1":"Egg yolk.","e1t":"Yumurta sarısı.","e2":"Separate the white from the yolk.","e2t":"Akını sarısından ayırın."},{"w":"zeal","tr":"şevk / gayret / büyük heves","te":"Noun","tt":"İsim","de":"Great enthusiasm or eagerness","dt":"Büyük heves veya isteklilik","e1":"To work with religious zeal.","e1t":"Dini bir şevkle çalışmak.","e2":"Reformist zeal.","e2t":"Reformist gayret."},{"w":"zealous","tr":"gayretli / hevesli / ateşli","te":"Adjective","tt":"Sıfat","de":"Showing great enthusiasm or eagerness","dt":"Büyük heves veya isteklilik gösteren","e1":"A zealous supporter of the cause.","e1t":"Davanın ateşli (gayretli) bir destekçisi.","e2":"He is very zealous in his work.","e2t":"İşinde çok gayretlidir."},{"w":"zenith","tr":"zirve / doruk / başucu noktası","te":"Noun","tt":"İsim","de":"The most successful time; or the highest point in the sky","dt":"En başarılı zaman; veya gökyüzündeki en yüksek nokta","e1":"At the zenith of his career.","e1t":"Kariyerinin zirvesinde.","e2":"The sun reached its zenith.","e2t":"Güneş en tepe noktasına ulaştı."},{"w":"zero","tr":"sıfır / hiç / sıfırlamak","te":"Number/Noun/Verb","tt":"The number 0; or nothing","de":"0 sayısı; veya hiçlik","dt":"Five degrees below zero.","e1":"Sıfırın altında beş derece.","e1t":"To zero in on something (to focus).","e2":"Bir şeye odaklanmak (hedefe kilitlenmek).","e2t":""},{"w":"zest","tr":"keyif / lezzet / şevk / (limon vb.) kabuğu","te":"Noun/Verb","tt":"İsim/Fiil","de":"Great enthusiasm and energy; or the outer skin of an orange","dt":"Büyük heves ve enerji; veya portakalın dış kabuğu","e1":"To have a zest for life.","e1t":"Yaşama sevinci (keyfi) olmak.","e2":"Add some lemon zest to the cake.","e2t":"Keke biraz limon kabuğu rendesi ekle."},{"w":"zigzag / zig","tr":"zag","te":"zikzak / zikzak çizmek","tt":"Noun/Adj/Verb/Adv","de":"A line that moves from side to side in sharp turns","dt":"Keskin dönüşlerle yanlara doğru hareket eden çizgi","e1":"A zigzag path up the mountain.","e1t":"Dağa çıkan zikzaklı bir yol.","e2":"The car zigzagged across the road.","e2t":"Araba yolda zikzaklar çizerek ilerledi."},{"w":"zinc","tr":"çinko","te":"Noun/Verb","tt":"İsim/Fiil","de":"A blue","dt":"white metal used to protect other metals","e1":"Diğer metalleri korumak için kullanılan mavi","e1t":"beyaz metal","e2":"Zinc is used in batteries.","e2t":"Çinko pillerde kullanılır."},{"w":"zip","tr":"fermuar / vınlamak / hızla gitmek / sıkıştırmak (dosya)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device used to fasten clothes; or to move quickly; or to compress a file","dt":"Kıyafetleri bağlamak için kullanılan araç; veya hızla gitmek; veya dosya sıkıştırmak","e1":"To undo a zip.","e1t":"Fermuar açmak.","e2":"He zipped through the work.","e2t":"İşi vınlayıp (hızla) bitirdi."},{"w":"zone","tr":"bölge / kuşak / alan / bölgeye ayırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An area that is different from others for a reason","dt":"Bir nedenle diğerlerinden farklı olan alan","e1":"Time zone.","e1t":"Saat dilimi.","e2":"Comfort zone.","e2t":"Konfor alanı."},{"w":"zoo","tr":"hayvanat bahçesi","te":"Noun","tt":"İsim","de":"A place where many kinds of wild animals are kept","dt":"Birçok vahşi hayvan türünün tutulduğu yer","e1":"To visit the zoo.","e1t":"Hayvanat bahçesini ziyaret etmek.","e2":"This place is a zoo! (very crowded/messy).","e2t":"Burası tımarhane (çok kalabalık/karışık) gibi!"},{"w":"zoology","tr":"zooloji / hayvan bilimi","te":"Noun","tt":"İsim","de":"The scientific study of animals","dt":"Hayvanların bilimsel olarak incelenmesi","e1":"A professor of zoology.","e1t":"Zooloji profesörü.","e2":"To study zoology at university.","e2t":"Üniversitede zooloji okumak."},{"w":"zoom","tr":"yakınlaştırmak / hızla gitmek / vınlama","te":"Verb/Noun","tt":"Fiil/İsim","de":"To change from a long","dt":"distance view to a close","e1":"up; or to move fast","e1t":"Uzak çekimden yakın çekime geçmek; veya hızlı hareket etmek","e2":"To zoom in on a face.","e2t":"Bir yüze odaklanmak (yakınlaşmak)."},{"w":"c1","tr":"","te":"","tt":"","de":"","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"abate","tr":"azalmak / dinmek / hafiflemek","te":"Verb","tt":"Fiil","de":"To become less strong or to make something less strong","dt":"Daha az güçlü hale gelmek veya getirmek","e1":"The storm showed no signs of abating.","e1t":"Fırtına dinme belirtisi göstermedi.","e2":"Steps to abate noise pollution.","e2t":"Gürültü kirliliğini azaltmaya yönelik adımlar."},{"w":"aberration","tr":"sapma / yanılma / anormallik","te":"Noun","tt":"İsim","de":"A temporary change from what is typical or accepted","dt":"Tipik veya kabul edilenden geçici bir sapma","e1":"In a moment of aberration, she agreed to the deal.","e1t":"Bir anlık yanılmayla anlaşmayı kabul etti.","e2":"Chromatic aberration.","e2t":"(Optikte) renk sapması."},{"w":"abhor","tr":"tiksinmek / nefret etmek","te":"Verb","tt":"Fiil","de":"To hate a way of behaving or thinking, often for moral reasons","dt":"Bir davranış veya düşünce biçiminden (genellikle ahlaki nedenlerle) nefret etmek","e1":"I abhor all forms of racism.","e1t":"Irkçılığın her türlüsünden nefret ederim (tiksinirim).","e2":"To abhor violence.","e2t":"Şiddetten tiksinmek."},{"w":"abject","tr":"sefil / perişan / aşağılık","te":"Adjective","tt":"Sıfat","de":"Extreme and showing no hope; or without any pride","dt":"Umutsuz ve aşırı; veya gurursuzca","e1":"Abject poverty.","e1t":"Sefil (aşırı) yoksulluk.","e2":"An abject apology.","e2t":"Ezikçe (aşağılık bir şekilde) özür dileme."},{"w":"abolish","tr":"yürürlükten kaldırmak / feshetmek","te":"Verb","tt":"Fiil","de":"To end an activity or custom officially","dt":"Bir faaliyeti veya geleneği resmi olarak sona erdirmek","e1":"To abolish slavery.","e1t":"Köleliği kaldırmak.","e2":"The government plans to abolish the inheritance tax.","e2t":"Hükümet veraset vergisini kaldırmayı planlıyor."},{"w":"abrasive","tr":"yıpratıcı / aşındırıcı / kaba","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Rude and unfriendly; or a substance used for rubbing","dt":"Kaba ve dostça olmayan; veya aşındırıcı madde","e1":"She has a rather abrasive manner.","e1t":"Oldukça kaba (yıpratıcı) bir tavrı var.","e2":"Abrasive cleaners.","e2t":"Aşındırıcı temizleyiciler."},{"w":"abrupt","tr":"ani / sert / sarp","te":"Adjective","tt":"Sıfat","de":"Sudden and unexpected; or brief and unfriendly","dt":"Ani ve beklenmedik; veya kısa ve kaba","e1":"An abrupt change in policy.","e1t":"Politikada ani bir değişiklik.","e2":"He was rather abrupt with me.","e2t":"Bana karşı oldukça sert (kaba) davrandı."},{"w":"absentee","tr":"devamsız kişi / bulunmayan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is not at the place where they were expected","dt":"Beklenen yerde bulunmayan kişi","e1":"Absentee voters.","e1t":"(Sandığa gitmeyen) devamsız seçmenler.","e2":"The number of absentees is rising.","e2t":"Devamsızların sayısı artıyor."},{"w":"absolve","tr":"aklamak / beraat ettirmek / günahtan arındırmak","te":"Verb","tt":"Fiil","de":"To free someone from guilt, blame, or responsibility","dt":"Birini suçtan, ayıptan veya sorumluluktan kurtarmak","e1":"The report absolves her of any blame.","e1t":"Rapor onu her türlü suçlamadan aklıyor.","e2":"To absolve someone from their sins.","e2t":"Birini günahlarından arındırmak."},{"w":"abstain","tr":"kaçınmak / çekimser kalmak","te":"Verb","tt":"Fiil","de":"To not do something you enjoy; or to not vote","dt":"Zevk alınan bir şeyi yapmamak; veya oy kullanmamak","e1":"To abstain from alcohol.","e1t":"Alkolden kaçınmak (içmemek).","e2":"Ten people voted in favor and five abstained.","e2t":"On kişi lehte oy kullandı, beş kişi çekimser kaldı."},{"w":"abstracted","tr":"dalgın / düşünceli","te":"Adjective","tt":"Sıfat","de":"Thinking about something else and not noticing surroundings","dt":"Başka bir şeyi düşünürken çevresini fark etmeme durumu","e1":"He had an abstracted look on his face.","e1t":"Yüzünde dalgın bir ifade vardı.","e2":"She seemed abstracted.","e2t":"Dalgın görünüyordu."},{"w":"abundance","tr":"bolluk / bereket","te":"Noun","tt":"İsim","de":"A very large quantity of something","dt":"Bir şeyin çok büyük miktarda olması","e1":"An abundance of food.","e1t":"Yemek bolluğu.","e2":"Natural resources in abundance.","e2t":"Bol miktarda doğal kaynak."},{"w":"accolade","tr":"övgü / takdir / nişan","te":"Noun","tt":"İsim","de":"Praise and approval","dt":"Övgü ve onay","e1":"The hotel has won numerous accolades.","e1t":"Otel sayısız övgü (ödül) kazandı.","e2":"The highest accolade a scientist can receive.","e2t":"Bir bilim insanının alabileceği en yüksek takdir."},{"w":"accomplice","tr":"suç ortağı","te":"Noun","tt":"İsim","de":"A person who helps someone else to commit a crime","dt":"Birinin suç işlemesine yardım eden kişi","e1":"He was arrested as an accomplice to the murder.","e1t":"Cinayetin suç ortağı olarak tutuklandı.","e2":"An unwilling accomplice.","e2t":"İstem dışı suç ortağı."},{"w":"accost","tr":"laf atmak / rahatsız etmek / önünü kesmek","te":"Verb","tt":"Fiil","de":"To go up to someone and speak to them in a threatening way","dt":"Birine yaklaşıp tehditkar veya kaba bir şekilde konuşmak","e1":"I was accosted by a beggar.","e1t":"Bir dilenci tarafından önüm kesildi (rahatsız edildim).","e2":"She was accosted in the street.","e2t":"Sokakta laf atılarak rahatsız edildi."},{"w":"acquiescence","tr":"rıza / boyun eğme","te":"Noun","tt":"İsim","de":"The reluctant acceptance of something without protest","dt":"Bir şeyi protesto etmeden, isteksizce kabul etme","e1":"Her silent acquiescence was taken as agreement.","e1t":"Onun sessiz rızası anlaşma olarak kabul edildi.","e2":"Reluctant acquiescence.","e2t":"İsteksizce boyun eğme."},{"w":"acquit","tr":"beraat ettirmek / aklamak","te":"Verb","tt":"Fiil","de":"To decide officially in a court that someone is not guilty","dt":"Mahkemede birinin suçsuz olduğuna resmi olarak karar vermek","e1":"He was acquitted of all charges.","e1t":"Tüm suçlamalardan beraat etti.","e2":"To acquit oneself (to perform well).","e2t":"Bekleneni vermek (bir işten alnının akıyla çıkmak)."},{"w":"acuity","tr":"keskinlik / duyarlılık","te":"Noun","tt":"İsim","de":"The ability to hear, see, or think accurately","dt":"Doğru şekilde duyma, görme veya düşünme yeteneği","e1":"Visual acuity.","e1t":"Görüş keskinliği.","e2":"Mental acuity.","e2t":"Zihinsel keskinlik (kavrayış gücü)."},{"w":"acumen","tr":"sezgi gücü / zeka / kavrayış","te":"Noun","tt":"İsim","de":"Skill in making correct decisions and judgments","dt":"Doğru kararlar ve yargılar verme becerisi","e1":"Business acumen.","e1t":"İş dünyasındaki sezgi gücü (zekası).","e2":"Political acumen.","e2t":"Siyasi kavrayış."},{"w":"adamant","tr":"kararlı / tavizsiz / sert","te":"Adjective","tt":"Sıfat","de":"Refusing to be persuaded or to change one's mind","dt":"İkna edilmeyi veya fikrini değiştirmeyi reddeden","e1":"He was adamant that he would not resign.","e1t":"İstifa etmeyeceği konusunda kararlıydı.","e2":"An adamant refusal.","e2t":"Tavizsiz bir ret."},{"w":"adept","tr":"usta / mahir / becerikli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having a natural ability to do something that needs skill","dt":"Beceri gerektiren bir şeyi yapma konusunda doğal yeteneği olan","e1":"He is adept at fixing computers.","e1t":"Bilgisayar tamiri konusunda ustadır.","e2":"An adept negotiator.","e2t":"Mahir bir müzakereci."},{"w":"admonish","tr":"uyarmak / ikaz etmek / öğüt vermek","te":"Verb","tt":"Fiil","de":"To tell someone that they have done something wrong","dt":"Birine yanlış bir şey yaptığını (resmi veya nazikçe) söylemek","e1":"Her teacher admonished her for being late.","e1t":"Öğretmeni onu geç kaldığı için ikaz etti (uyardı).","e2":"To admonish someone against doing something.","e2t":"Birini bir şeyi yapmaması konusunda uyarmak."},{"w":"adorn","tr":"süslemek / donatmak","te":"Verb","tt":"Fiil","de":"To add something decorative to a person or thing","dt":"Birine veya bir şeye dekoratif bir şey eklemek","e1":"Gold framed mirrors adorned the walls.","e1t":"Altın çerçeveli aynalar duvarları süslüyordu.","e2":"To adorn oneself with jewelry.","e2t":"Kendini takılarla süslemek."},{"w":"adrift","tr":"başıboş / sürüklenen / amaçsız","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Floating on the water without being tied; or without a goal","dt":"Su üzerinde bağlı olmadan yüzen; veya amaçsız","e1":"The boat was left adrift.","e1t":"Tekne başıboş (sürüklenmeye) bırakıldı.","e2":"He felt adrift after losing his job.","e2t":"İşini kaybettikten sonra kendini amaçsız (boşlukta) hissetti."},{"w":"adversity","tr":"sıkıntı / zorluk / talihsizlik","te":"Noun","tt":"İsim","de":"A difficult or unlucky situation","dt":"Zor veya talihsiz durum","e1":"To show courage in the face of adversity.","e1t":"Zorluklar karşısında cesaret göstermek.","e2":"Overcoming adversity.","e2t":"Sıkıntıların üstesinden gelmek."},{"w":"aerial","tr":"havaya ait / havadan / anten","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"In or from the air; or a metal structure for radio/TV","dt":"Havada olan veya havadan gelen; veya anten","e1":"An aerial photograph.","e1t":"Havadan çekilmiş fotoğraf.","e2":"Aerial combat.","e2t":"Hava savaşı."},{"w":"affability","tr":"sokulganlık / naziklik","te":"Noun","tt":"İsim","de":"The quality of being affable; geniality","dt":"Nazik ve cana yakın olma niteliği","e1":"His natural affability made him very popular.","e1t":"Doğal cana yakınlığı onu çok popüler yaptı.","e2":"Remarkable affability.","e2t":"Dikkat çekici naziklik."},{"w":"affable","tr":"dost canlısı / nazik / sokulgan","te":"Adjective","tt":"Sıfat","de":"Friendly and easy to talk to","dt":"Dost canlısı ve konuşması kolay","e1":"An affable host.","e1t":"Nazik (cana yakın) bir ev sahibi.","e2":"He was in an affable mood.","e2t":"Dost canlısı bir ruh halindeydi."},{"w":"affinity","tr":"yakınlık / benzerlik / çekim","te":"Noun","tt":"İsim","de":"A feeling that you understand someone; or a similarity","dt":"Birini anladığını hissetme; veya benzerlik","e1":"To have an affinity for music.","e1t":"Müziğe karşı bir yatkınlığı (yakınlığı) olmak.","e2":"The natural affinity between the two species.","e2t":"İki tür arasındaki doğal benzerlik (yakınlık)."},{"w":"affluent","tr":"varlıklı / zengin / gani","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having a lot of money or owning a lot of things","dt":"Çok parası olan veya çok şeye sahip olan","e1":"An affluent neighborhood.","e1t":"Varlıklı (zengin) bir mahalle.","e2":"Affluent lifestyle.","e2t":"Lüks (zengin) yaşam tarzı."},{"w":"aggravate","tr":"ağırlaştırmak / kötüleştirmek / kışkırtmak","te":"Verb","tt":"Fiil","de":"To make a problem or injury worse; or to annoy","dt":"Bir sorunu veya yarayı daha kötü hale getirmek; veya kızdırmak","e1":"Stress can aggravate your medical condition.","e1t":"Stres tıbbi durumunuzu ağırlaştırabilir.","e2":"Aggravate the situation.","e2t":"Durumu kötüleştirmek."},{"w":"agitate","tr":"kışkırtmak / çalkalamak / huzursuz etmek","te":"Verb","tt":"Fiil","de":"To argue forcefully for something; or to shake a liquid","dt":"Bir şey için güçlü bir şekilde tartışmak (kışkırtmak); veya bir sıvıyı çalkalamak","e1":"To agitate for political change.","e1t":"Siyasi değişim için kışkırtmak (kampanya yürütmek).","e2":"Agitate the mixture before use.","e2t":"Kullanmadan önce karışımı çalkalayın."},{"w":"ailment","tr":"rahatsızlık / hafif hastalık","te":"Noun","tt":"İsim","de":"An illness, usually not a serious one","dt":"Genellikle ciddi olmayan hastalık","e1":"Common childhood ailments.","e1t":"Yaygın çocukluk hastalıkları.","e2":"To suffer from a minor ailment.","e2t":"Hafif bir rahatsızlıktan muzdarip olmak."},{"w":"airborne","tr":"havadan taşınan / havadaki / uçuşta","te":"Adjective","tt":"Sıfat","de":"Carried through the air; or in the air","dt":"Havadan taşınan; veya havada olan","e1":"Airborne viruses.","e1t":"Havadan taşınan virüsler.","e2":"The plane is now airborne.","e2t":"Uçak şu an havada (kalkış yaptı)."},{"w":"align","tr":"hizalamak / aynı çizgiye getirmek / desteklemek","te":"Verb","tt":"Fiil","de":"To put things in a straight line; or to support a group","dt":"Şeyleri düz bir çizgiye koymak; veya bir grubu desteklemek","e1":"Align the wheels.","e1t":"Tekerlekleri hizalamak.","e2":"To align yourself with a political party.","e2t":"Kendini bir siyasi partiyle aynı çizgiye getirmek (desteklemek)."},{"w":"allude","tr":"ima etmek / değinmek","te":"Verb","tt":"Fiil","de":"To speak about something in an indirect way","dt":"Bir şeyden dolaylı bir şekilde bahsetmek","e1":"He alluded to problems in his marriage.","e1t":"Evliliğindeki sorunlara imada bulundu (değindi).","e2":"To allude to a past event.","e2t":"Geçmişteki bir olayı ima etmek."},{"w":"allure","tr":"çekicilik / cazibe / cezbetmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The quality of being exciting and attractive","dt":"Heyecan verici ve çekici olma niteliği","e1":"The allure of the big city.","e1t":"Büyük şehrin cazibesi.","e2":"Sexual allure.","e2t":"Cinsel çekicilik."},{"w":"altercation","tr":"tartışma / ağız kavgası","te":"Noun","tt":"İsim","de":"A loud or angry argument","dt":"Yüksek sesli veya öfkeli tartışma","e1":"A physical altercation.","e1t":"Fiziksel kavga (arbede).","e2":"To get into an altercation with someone.","e2t":"Biriyle ağız kavgasına girmek."},{"w":"altruism","tr":"özgecilik / fedakarlık / başkalarını düşünme","te":"Noun","tt":"İsim","de":"Helping others without thinking about yourself","dt":"Kendini düşünmeden başkalarına yardım etme","e1":"Pure altruism.","e1t":"Saf özgecilik.","e2":"Acts of altruism.","e2t":"Fedakarlık eylemleri."},{"w":"amalgamate","tr":"birleştirmek / şirket evliliği yapmak / cıvayla karışmak","te":"Verb/Adjective","tt":"To join together to form one large organization","de":"Tek bir büyük organizasyon oluşturmak için birleşmek","dt":"The two schools were amalgamated.","e1":"İki okul birleştirildi.","e1t":"To amalgamate different ideas.","e2":"Farklı fikirleri bir araya getirmek (harmanlamak).","e2t":""},{"w":"ambience","tr":"ambiyans / hava","te":"Noun","tt":"İsim","de":"The character and atmosphere of a place","dt":"Bir yerin karakteri ve atmosferi","e1":"The restaurant has a very romantic ambience.","e1t":"Restoranın çok romantik bir ambiyansı var.","e2":"Relaxing ambience.","e2t":"Rahatlatıcı ortam."},{"w":"ambivalence","tr":"kararsızlık / ikilem / çelişkili duygular","te":"Noun","tt":"İsim","de":"Having two opposing feelings at the same time","dt":"Aynı anda iki zıt duyguya sahip olma","e1":"Her ambivalence towards her job.","e1t":"İşine karşı hissettiği çelişkili duygular (kararsızlık).","e2":"To be in a state of ambivalence.","e2t":"İkilem içinde olmak."},{"w":"amicable","tr":"dostça / barışçıl / kavgasız","te":"Adjective","tt":"Sıfat","de":"Done in a friendly way without argument","dt":"Tartışmasız, dostça bir şekilde yapılan","e1":"An amicable divorce.","e1t":"Anlaşmalı (dostça) boşanma.","e2":"An amicable settlement.","e2t":"Barışçıl bir çözüm (uzlaşma)."},{"w":"amplify","tr":"güçlendirmek / sesini yükseltmek / detaylandırmak","te":"Verb","tt":"Fiil","de":"To make something louder or stronger","dt":"Bir şeyi daha yüksek sesli veya daha güçlü yapmak","e1":"To amplify a signal.","e1t":"Bir sinyali güçlendirmek.","e2":"Amplified music.","e2t":"Amfiden yükseltilmiş müzik."},{"w":"analogy","tr":"benzetme / analoji / benzerlik","te":"Noun","tt":"İsim","de":"A comparison between things that have similar features","dt":"Benzer özelliklere sahip şeyler arasındaki karşılaştırma","e1":"To draw an analogy between the brain and a computer.","e1t":"Beyin ile bilgisayar arasında bir benzetme yapmak.","e2":"By analogy with...","e2t":"... ile analoji yoluyla."},{"w":"animosity","tr":"düşmanlık / nefret / kin","te":"Noun","tt":"İsim","de":"A strong feeling of opposition or anger","dt":"Güçlü bir muhalefet veya öfke hissi","e1":"There is no personal animosity between them.","e1t":"Aralarında kişisel bir düşmanlık yok.","e2":"To show animosity toward someone.","e2t":"Birine karşı kin (nefret) göstermek."},{"w":"annex","tr":"toprak ilhak etmek / eklemek / ek bina","te":"Verb/Noun","tt":"Fiil/İsim","de":"To take control of another country's land; or an extra building","dt":"Başka bir ülkenin toprağını kontrol altına almak; veya ek bina","e1":"Germany annexed Austria in 1938.","e1t":"Almanya 1938'de Avusturya'yı ilhak etti.","e2":"A hotel annex.","e2t":"Otelin ek binası."},{"w":"annexation","tr":"ilhak / topraklarına katma","te":"Noun","tt":"İsim","de":"The action of annexing something, especially territory","dt":"Özellikle bir toprağın zorla ele geçirilip ülkeye katılması","e1":"The annexation of the neighboring island.","e1t":"Komşu adanın ilhakı.","e2":"Illegal annexation.","e2t":"Yasa dışı ilhak."},{"w":"annihilate","tr":"yok etmek / yerle bir etmek / bozguna uğratmak","te":"Verb","tt":"Fiil","de":"To destroy something completely","dt":"Bir şeyi tamamen yok etmek","e1":"","e1t":"","e2":"","e2t":""},{"w":"anomaly","tr":"anormallik / sapma","te":"Noun","tt":"İsim","de":"Something that is unusual or different from what is standard","dt":"Standart olandan farklı veya sıra dışı olan şey","e1":"A statistical anomaly.","e1t":"İstatistiksel bir anormallik.","e2":"The discovery was an anomaly in his otherwise normal research.","e2t":"Bu keşif, onun normal araştırmasında bir sapmaydı."},{"w":"antidote","tr":"panzehir / çare","te":"Noun","tt":"İsim","de":"A substance that stops the effects of a poison; or a way of preventing something bad","dt":"Zehrin etkisini durduran madde; veya kötü bir şeyi önleme yolu","e1":"There is no known antidote to this poison.","e1t":"Bu zehrin bilinen bir panzehiri yok.","e2":"Laughter is a wonderful antidote to stress.","e2t":"Gülmek, stres için harika bir çaredir."},{"w":"antiseptic","tr":"mikropsavar / antiseptik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"A chemical used for cleaning wounds to prevent infection","dt":"Enfeksiyonu önlemek için yaraları temizlemede kullanılan kimyasal","e1":"Antiseptic cream.","e1t":"Antiseptik krem.","e2":"Clean the wound with an antiseptic.","e2t":"Yarayı bir mikropsavar ile temizleyin."},{"w":"apathetic","tr":"ilgisiz / kayıtsız","te":"Adjective","tt":"Sıfat","de":"Showing no interest or enthusiasm","dt":"Hiç ilgi veya heves göstermeyen","e1":"Young people are often accused of being apathetic about politics.","e1t":"Gençler sık sık siyasete karşı ilgisiz olmakla suçlanıyor.","e2":"An apathetic response.","e2t":"Kayıtsız bir tepki."},{"w":"appalling","tr":"korkunç / dehşet verici","te":"Adjective","tt":"Sıfat","de":"Very bad; shocking","dt":"Çok kötü; şoke edici","e1":"Appalling weather conditions.","e1t":"Korkunç hava koşulları.","e2":"The prison conditions were appalling.","e2t":"Hapishane koşulları dehşet vericiydi."},{"w":"apparition","tr":"hayalet / hortlak / hayal","te":"Noun","tt":"İsim","de":"A ghost or ghost","dt":"like image of a person","e1":"Bir kişinin hayaleti veya hayalet benzeri görüntüsü","e1t":"He claimed to have seen an apparition of his late wife.","e2":"Rahmetli eşinin hayaletini gördüğünü iddia etti.","e2t":"A ghostly apparition."},{"w":"appease","tr":"yatıştırmak / taviz vererek barış sağlamak","te":"Verb","tt":"Fiil","de":"To prevent further disagreement by giving the other side what they want","dt":"Karşı tarafa istediğini vererek daha fazla anlaşmazlığı önlemek","e1":"To appease the angry crowd.","e1t":"Öfkeli kalabalığı yatıştırmak.","e2":"The government tried to appease the protesters.","e2t":"Hükümet protestocuları yatıştırmaya çalıştı."},{"w":"applaud","tr":"alkışlamak / takdir etmek","te":"Verb","tt":"Fiil","de":"To hit your hands together to show approval; or to praise","dt":"Onay göstermek için elleri birbirine vurmak; veya övmek","e1":"The audience applauded loudly.","e1t":"Dinleyiciler yüksek sesle alkışladı.","e2":"We applaud her decision to resign.","e2t":"Onun istifa etme kararını takdir ediyoruz."},{"w":"apprehend","tr":"tutuklamak / kavramak / endişeyle beklemek","te":"Verb","tt":"Fiil","de":"To catch and arrest someone; or to understand","dt":"Birini yakalamak ve tutuklamak; veya anlamak","e1":"The police managed to apprehend the suspect.","e1t":"Polis şüpheliyi tutuklamayı başardı.","e2":"To apprehend the danger.","e2t":"Tehlikeyi kavramak (sezmek)."},{"w":"apprise","tr":"bilgilendirmek / haber vermek","te":"Verb","tt":"Fiil","de":"To tell or inform someone about something","dt":"Birine bir şey hakkında bilgi vermek","e1":"Please keep me apprised of any developments.","e1t":"Lütfen gelişmelerden beni haberdar edin (bilgilendirin).","e2":"He apprised the committee of the situation.","e2t":"Komiteye durum hakkında bilgi verdi."},{"w":"arduous","tr":"zahmetli / çetin / yorucu","te":"Adjective","tt":"Sıfat","de":"Needing a lot of effort and energy","dt":"Çok fazla çaba ve enerji gerektiren","e1":"An arduous journey across the desert.","e1t":"Çöl boyunca yapılan zahmetli bir yolculuk.","e2":"The work was arduous and poorly paid.","e2t":"İş yorucu ve düşük ücretliydi."},{"w":"ascribe","tr":"atfetmek /","te":"e bağlamak","tt":"Verb","de":"Fiil","dt":"To believe or say that something is caused by something else","e1":"Bir şeyin başka bir şeyden kaynaklandığına inanmak veya söylemek","e1t":"To ascribe a poem to a famous writer.","e2":"Bir şiiri ünlü bir yazara atfetmek.","e2t":"He ascribes his success to hard work."},{"w":"assertive","tr":"kendinden emin / iddialı / girişken","te":"Adjective","tt":"Sıfat","de":"Behaving confidently and clearly stating your opinions","dt":"Güvenle davranan ve fikirlerini net bir şekilde ifade eden","e1":"You need to be more assertive in meetings.","e1t":"Toplantılarda daha girişken (kendinden emin) olmalısın.","e2":"Assertive behavior.","e2t":"İddialı davranış."},{"w":"astounding","tr":"şaşırtıcı / hayret verici","te":"Adjective","tt":"Sıfat","de":"Very surprising or shocking","dt":"Çok şaşırtıcı veya şok edici","e1":"An astounding achievement.","e1t":"Hayret verici bir başarı.","e2":"The results of the test were astounding.","e2t":"Testin sonuçları şaşırtıcıydı."},{"w":"astute","tr":"zeki / kurnaz / açıkgöz","te":"Adjective","tt":"Sıfat","de":"Able to understand situations quickly and use this to your advantage","dt":"Durumları hızla anlayabilen ve bunu avantajına kullanabilen","e1":"An astute businessman.","e1t":"Zeki bir iş adamı.","e2":"She made some astute observations.","e2t":"Bazı kurnazca (isabetli) gözlemler yaptı."},{"w":"atonement","tr":"kefaret / telafi","te":"Noun","tt":"İsim","de":"Something that you do to show you are sorry for something bad","dt":"Yapılan kötü bir şey için üzgün olduğunu göstermek amacıyla yapılan şey","e1":"He sent flowers as a gesture of atonement.","e1t":"Kefaret göstergesi olarak çiçek gönderdi.","e2":"Day of Atonement.","e2t":"(Dini) Kefaret Günü."},{"w":"atrocious","tr":"berbat / canice / vahşi","te":"Adjective","tt":"Sıfat","de":"Very bad or cruel","dt":"Çok kötü veya zalimce","e1":"Atrocious weather.","e1t":"Berbat hava.","e2":"An atrocious crime.","e2t":"Canice bir suç."},{"w":"attribute","tr":"bağlamak (neden olarak) / özellik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To say that something is the result of something; or a quality","dt":"Bir şeyin bir sonucun nedeni olduğunu söylemek; veya özellik","e1":"She attributes her health to a strict diet.","e1t":"Sağlığını sıkı bir diyete bağlıyor.","e2":"Organizational ability is an essential attribute for this job.","e2t":"Organizasyon yeteneği bu iş için temel bir özelliktir."},{"w":"atypical","tr":"tipik olmayan / kural dışı","te":"Adjective","tt":"Sıfat","de":"Not typical; unusual","dt":"Tipik olmayan; sıra dışı","e1":"An atypical response to the drug.","e1t":"İlacın alışılmadık (tipik olmayan) bir etkisi.","e2":"This is an atypical case.","e2t":"Bu kural dışı (farklı) bir vaka."},{"w":"audacious","tr":"cesur / cüretkâr / küstah","te":"Adjective","tt":"Sıfat","de":"Showing a willingness to take risks or being shockingly rude","dt":"Risk alma isteği gösteren veya şaşırtıcı derecede kaba","e1":"An audacious plan.","e1t":"Cüretkâr (cesur) bir plan.","e2":"An audacious remark.","e2t":"Küstahça bir söz."},{"w":"augment","tr":"artırmak / çoğaltmak","te":"Verb","tt":"Fiil","de":"To increase the size or value of something","dt":"Bir şeyin boyutunu veya değerini artırmak","e1":"He augmented his income by driving a taxi.","e1t":"Taksi sürerek gelirini artırdı.","e2":"Augmented reality (AR).","e2t":"Artırılmış gerçeklik."},{"w":"auspicious","tr":"uğurlu / gelecek vadeden","te":"Adjective","tt":"Sıfat","de":"Suggesting a positive and successful future","dt":"Olumlu ve başarılı bir gelecek vadeden","e1":"An auspicious start to the new year.","e1t":"Yeni yıla uğurlu bir başlangıç.","e2":"The stars were in an auspicious position.","e2t":"Yıldızlar uğurlu bir konumdaydı."},{"w":"austere","tr":"sade / katı / sert","te":"Adjective","tt":"Sıfat","de":"Simple and without decoration; or very strict","dt":"Süslemesiz ve sade; veya çok katı","e1":"An austere bedroom.","e1t":"Sade (gösterişsiz) bir yatak odası.","e2":"An austere teacher.","e2t":"Sert (disiplinli) bir öğretmen."},{"w":"aversion","tr":"tiksinti / nefret / kaçınma","te":"Noun","tt":"İsim","de":"A strong feeling of dislike or of not wanting to do something","dt":"Güçlü bir hoşlanmama veya bir şeyi yapmama isteği","e1":"He has a strong aversion to dogs.","e1t":"Köpeklere karşı güçlü bir antipatisi (nefreti) var.","e2":"Risk aversion.","e2t":"Riskten kaçınma."},{"w":"awe","tr":"derin saygı / hayranlık / huşu","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of great respect mixed with fear or surprise","dt":"Korku veya şaşkınlıkla karışık büyük bir saygı hissi","e1":"I watched the mountains in awe.","e1t":"Dağları hayranlıkla (huşu içinde) izledim.","e2":"To be in awe of someone.","e2t":"Birine karşı derin saygı duymak."},{"w":"awkwardness","tr":"sakarlık / beceriksizlik / mahcubiyet","te":"Noun","tt":"İsim","de":"The quality of being clumsy or causing embarrassment","dt":"Sakar olma veya mahcubiyete neden olma niteliği","e1":"He suffered from extreme social awkwardness.","e1t":"Aşırı sosyal beceriksizlikten (çekingenlikten) muzdaripti.","e2":"The awkwardness of the situation.","e2t":"Durumun garipliği (mahcubiyeti)."},{"w":"backlash","tr":"sert tepki / geri tepme","te":"Noun","tt":"İsim","de":"A strong negative reaction by a large number of people","dt":"Çok sayıda insanın gösterdiği güçlü olumsuz tepki","e1":"A public backlash against tax increases.","e1t":"Vergi artışlarına karşı halkın sert tepkisi.","e2":"The backlash from the scandal.","e2t":"Skandalın geri tepmesi (sonuçları)."},{"w":"baffling","tr":"şaşırtıcı / kafa karıştırıcı","te":"Adjective","tt":"Sıfat","de":"Impossible to understand","dt":"Anlaşılması imkansız","e1":"A baffling mystery.","e1t":"Kafa karıştırıcı (esrarengiz) bir gizem.","e2":"His behavior is completely baffling to me.","e2t":"Davranışı benim için tamamen anlaşılmaz."},{"w":"balmy","tr":"ılık ve hoş / ferahlatıcı","te":"Adjective","tt":"Sıfat","de":"(Of weather) pleasantly warm","dt":"(Hava için) hoş bir şekilde ılık","e1":"A balmy summer evening.","e1t":"Ilık bir yaz akşamı.","e2":"Balmy air.","e2t":"Yumuşak (hoş) hava."},{"w":"banter","tr":"şakalaşmak / latife etmek / şaka","te":"Verb/Noun","tt":"Fiil/İsim","de":"To talk in a funny and friendly way","dt":"Komik ve dostça konuşmak","e1":"He enjoyed bantering with his colleagues.","e1t":"Meslektaşlarıyla şakalaşmaktan hoşlanırdı.","e2":"Friendly banter.","e2t":"Dostça latife."},{"w":"barrage","tr":"yoğun saldırı / baraj / yaylım ateşi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large number of things happening at the same time","dt":"Aynı anda gerçekleşen çok sayıda olay","e1":"A barrage of questions.","e1t":"Soru yağmuru.","e2":"To be hit by a barrage of criticism.","e2t":"Eleştiri bombardımanına tutulmak."},{"w":"barter","tr":"takas / değiş tokuş etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To exchange goods for other goods rather than money","dt":"Malı para yerine başka mallarla değiştirmek","e1":"They bartered grain for salt.","e1t":"Tuzu tahılla takas ettiler.","e2":"The barter system.","e2t":"Takas sistemi."},{"w":"beckon","tr":"çağırmak / el etmek / cazip gelmek","te":"Verb","tt":"Fiil","de":"To move your hand to tell someone to come near","dt":"Birine gelmesi için eliyle işaret etmek","e1":"She beckoned me to follow her.","e1t":"Takip etmem için bana el etti.","e2":"A bright future beckons.","e2t":"Parlak bir gelecek çağırıyor (cazip görünüyor)."},{"w":"befall","tr":"başa gelmek / vuku bulmak","te":"Verb","tt":"Fiil","de":"(Of something bad) to happen to someone","dt":"(Kötü bir şey için) birinin başına gelmek","e1":"We prayed that no harm would befall them.","e1t":"Başlarına bir kötülük gelmemesi için dua ettik.","e2":"Whatever may befall...","e2t":"Başa ne gelirse gelsin..."},{"w":"befitting","tr":"uygun / yaraşır","te":"Adjective","tt":"Sıfat","de":"Suitable or right for someone or something","dt":"Birine veya bir şeye uygun veya doğru olan","e1":"A reward befitting his efforts.","e1t":"Çabalarına yaraşır bir ödül.","e2":"It was a formal ceremony, befitting the occasion.","e2t":"Duruma uygun, resmi bir törendi."},{"w":"beguile","tr":"kandırmak / büyülemek / ayartmak","te":"Verb","tt":"Fiil","de":"To persuade or trick someone; or to charm someone","dt":"Birini ikna etmek veya kandırmak; veya birini etkilemek","e1":"He was beguiled by her beauty.","e1t":"Onun güzelliği tarafından büyülendi.","e2":"To beguile someone into doing something.","e2t":"Birini bir şeyi yapması için ayartmak."},{"w":"behead","tr":"başını kesmek / idam etmek","te":"Verb","tt":"Fiil","de":"To cut off the head of someone","dt":"Birinin başını kesmek","e1":"The king was beheaded during the revolution.","e1t":"Kral, devrim sırasında idam edildi (başı kesildi).","e2":"(Bkz: Execution).","e2t":""},{"w":"bellow","tr":"böğürmek / bağırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shout in a loud deep voice","dt":"Derin ve yüksek bir sesle bağırmak","e1":"He bellowed orders at his soldiers.","e1t":"Askerlerine emirler yağdırdı (bağırdı).","e2":"A bellow of pain.","e2t":"Acı bir böğürtü."},{"w":"bequest","tr":"miras bırakılan şey / vasiyet","te":"Noun","tt":"İsim","de":"Money or property that you arrange to give to someone after death","dt":"Ölümden sonra birine verilmek üzere ayarlanan para veya mülk","e1":"He left a large bequest to the university.","e1t":"Üniversiteye büyük bir miras bıraktı.","e2":"A charitable bequest.","e2t":"Hayır amaçlı vasiyet."},{"w":"berate","tr":"azarlamak / fırça atmak","te":"Verb","tt":"Fiil","de":"To speak angrily to someone because they have done wrong","dt":"Yanlış yaptıkları için birine öfkeyle konuşmak","e1":"His mother berated him for being late.","e1t":"Annesi geç kaldığı için onu azarladı.","e2":"To berate oneself.","e2t":"Kendi kendini suçlamak (azarlamak)."},{"w":"beseech","tr":"yalvarmak / istirham etmek","te":"Verb","tt":"Fiil","de":"To ask for something in a very emotional way","dt":"Çok duygusal bir şekilde bir şey istemek","e1":"\"Stay with me,\" she besought him.","e1t":"\"Benimle kal,\" diye yalvardı ona.","e2":"I beseech you to reconsider.","e2t":"Sizden tekrar düşünmenizi istirham ediyorum."},{"w":"bestow","tr":"vermek / bağışlamak / sunmak","te":"Verb","tt":"Fiil","de":"To give something as an honor or a gift","dt":"Bir şeyi onur veya hediye olarak vermek","e1":"The medal was bestowed on him by the Queen.","e1t":"Madalya ona Kraliçe tarafından sunuldu.","e2":"To bestow a title.","e2t":"Unvan vermek."},{"w":"biased","tr":"taraflı / ön yargılı","te":"Adjective","tt":"Sıfat","de":"Showing unfair support for or opposition to someone","dt":"Birine haksız destek veya karşıtlık gösteren","e1":"The report was heavily biased toward the government.","e1t":"Rapor hükümete karşı çok taraflıydı.","e2":"Biased information.","e2t":"Yanlı taraf tutan bilgi."},{"w":"bipartisan","tr":"iki partili / iki partinin desteklediği","te":"Adjective","tt":"Sıfat","de":"Supported by two political parties","dt":"İki siyasi parti tarafından desteklenen","e1":"A bipartisan agreement.","e1t":"İki partinin uzlaştığı anlaşma.","e2":"Bipartisan support.","e2t":"İki partili destek."},{"w":"blandishment","tr":"tatlı söz / pohpohlama","te":"Noun","tt":"İsim","de":"Pleasant words used to persuade someone","dt":"Birini ikna etmek için kullanılan hoş sözler","e1":"He was immune to her blandishments.","e1t":"Onun tatlı sözlerine karşı bağışıklığı vardı (kanmıyordu).","e2":"Subtle blandishments.","e2t":"İnce pohpohlamalar."},{"w":"blemish","tr":"leke / kusur / bozmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A mark that spoils the appearance of something","dt":"Bir şeyin görünüşünü bozan leke veya iz","e1":"A blemish on his record.","e1t":"Sicilinde bir leke.","e2":"Skin blemishes.","e2t":"Cilt lekeleri (kusurları)."},{"w":"blight","tr":"körelmek / mahvetmek / bitki hastalığı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To spoil or damage something; or a disease in plants","dt":"Bir şeyi bozmak veya zarar vermek; veya bitki hastalığı","e1":"His career was blighted by injury.","e1t":"Kariyeri sakatlık yüzünden mahvoldu (köreldi).","e2":"Urban blight.","e2t":"Şehirsel bozulma/çürüme."},{"w":"blunder","tr":"büyük hata / pot kırmak / hata yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A serious or stupid mistake","dt":"Ciddi veya aptalca bir hata","e1":"He committed a major tactical blunder.","e1t":"Büyük bir taktiksel hata yaptı.","e2":"To blunder into a room.","e2t":"Bir odaya sakarca (pat diye) girmek."},{"w":"bolster","tr":"desteklemek / güçlendirmek / yastık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To support or improve something","dt":"Bir şeyi desteklemek veya iyileştirmek","e1":"To bolster someone's confidence.","e1t":"Birinin güvenini artırmak (desteklemek).","e2":"High interest rates bolstered the currency.","e2t":"Yüksek faiz oranları para birimini güçlendirdi."},{"w":"bombard","tr":"bombardıman etmek / yağmuruna tutmak","te":"Verb","tt":"Fiil","de":"To attack with many missiles or questions","dt":"Birçok füze veya soruyla saldırmak","e1":"The city was bombarded for days.","e1t":"Şehir günlerce bombalandı.","e2":"I was bombarded with emails.","e2t":"E"},{"w":"bondage","tr":"esaret / kölelik","te":"Noun","tt":"İsim","de":"The state of being a slave or being forced to stay","dt":"Köle olma veya kalmaya zorlanma durumu","e1":"To free someone from bondage.","e1t":"Birini esaretten kurtarmak.","e2":"Human bondage.","e2t":"İnsan esareti."},{"w":"boorish","tr":"kaba / yontulmamış / saygısız","te":"Adjective","tt":"Sıfat","de":"Rude and not considering other people's feelings","dt":"Kaba ve başkalarının duygularını düşünmeyen","e1":"Boorish behavior.","e1t":"Saygısızca davranış.","e2":"He is a boorish man.","e2t":"Yontulmamış (kaba) bir adamdır."},{"w":"boundless","tr":"sınırsız / sonsuz / uçsuz bucaksız","te":"Adjective","tt":"Sıfat","de":"Having no limit","dt":"Hiçbir sınırı olmayan","e1":"Boundless energy.","e1t":"Bitmek tükenmek bilmeyen (sonsuz) enerji.","e2":"Her enthusiasm for the project was boundless.","e2t":"Projeye olan hevesi sınırsızdı."},{"w":"brandish","tr":"savurmak / sallamak (tehditvari)","te":"Verb","tt":"Fiil","de":"To wave something around in a dangerous or excited way","dt":"Bir şeyi tehlikeli veya heyecanlı bir şekilde etrafta sallamak","e1":"He was brandishing a knife.","e1t":"Elinde bir bıçak savuruyordu.","e2":"To brandish a weapon.","e2t":"Silah sallamak."},{"w":"breadth","tr":"genişlik / kapsam / enginlik","te":"Noun","tt":"İsim","de":"The distance from one side to the other; or a wide range","dt":"Bir yanından diğer yanına olan mesafe; veya geniş kapsam","e1":"The breadth of the river.","e1t":"Nehrin genişliği.","e2":"The breadth of his knowledge is amazing.","e2t":"Bilgisinin enginliği (kapsamı) şaşırtıcı."},{"w":"brevity","tr":"özlülük / kısalık","te":"Noun","tt":"İsim","de":"The quality of using few words or lasting a short time","dt":"Az kelime kullanma veya kısa sürme niteliği","e1":"Brevity is the soul of wit.","e1t":"Kısalık (özlülük) zekanın özüdür.","e2":"For the sake of brevity.","e2t":"Kısa kesmek (özlülük) adına."},{"w":"broach","tr":"(konuyu) açmak / dile getirmek","te":"Verb","tt":"Fiil","de":"To begin a discussion of something difficult","dt":"Zor bir konunun tartışmasını başlatmak","e1":"She finally broached the subject of money.","e1t":"Sonunda para konusunu açtı.","e2":"To broach a sensitive issue.","e2t":"Hassas bir meseleyi dile getirmek."},{"w":"brute","tr":"kaba kuvvet / vahşi / hayvani","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A cruel, violent person; or using physical strength only","dt":"Zalim, şiddet yanlısı kişi; veya sadece fiziksel güç kullanan","e1":"Brute force.","e1t":"Kaba kuvvet.","e2":"He is a complete brute.","e2t":"O tam bir vahşi (kaba adam)."},{"w":"buck","tr":"karşı koymak / direnmek / sıçramak (at)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To oppose or refuse to follow something; or a male animal","dt":"Bir şeye karşı gelmek veya uymayı reddetmek; veya erkek hayvan","e1":"To buck the trend.","e1t":"Akıma (trende) karşı koymak.","e2":"The horse bucked and threw the rider.","e2t":"At şahlandı (çifte attı) ve biniciyi fırlattı."},{"w":"budding","tr":"gelişmekte olan / yeni başlayan / tomurcuklanan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Beginning to develop or show promise","dt":"Gelişmeye veya gelecek vadetmeye başlayan","e1":"A budding romance.","e1t":"Yeni başlayan (filizlenen) bir aşk.","e2":"A budding artist.","e2t":"Gelecek vadeden (genç) bir sanatçı."},{"w":"buoyant","tr":"canlı / neşeli / (ekonomi) hareketli / batmayan","te":"Adjective","tt":"Sıfat","de":"Successful or happy; or able to float","dt":"Başarılı veya mutlu; veya su yüzünde kalabilen","e1":"A buoyant economy.","e1t":"Hareketli (canlı) bir ekonomi.","e2":"In a buoyant mood.","e2t":"Neşeli bir ruh halinde."},{"w":"burdensome","tr":"külfetli / ağır / zahmetli","te":"Adjective","tt":"Sıfat","de":"Causing difficulties or work","dt":"Zorluklara veya iş yüküne neden olan","e1":"Burdensome regulations.","e1t":"Külfetli (ağır) düzenlemeler.","e2":"A burdensome task.","e2t":"Zahmetli bir görev."},{"w":"burgeon","tr":"hızla gelişmek / serpilmek / tomurcuklanmak","te":"Verb","tt":"Fiil","de":"To develop or grow quickly","dt":"Hızla gelişmek veya büyümek","e1":"The city's burgeoning population.","e1t":"Şehrin hızla artan (serpilen) nüfusu.","e2":"A burgeoning market.","e2t":"Gelişmekte olan (büyüyen) bir pazar."},{"w":"burly","tr":"iri yarı / yapılı / güçlü","te":"Adjective","tt":"Sıfat","de":"(Of a man) large and strong","dt":"(Erkek için) iri ve güçlü","e1":"A burly policeman.","e1t":"İri yarı bir polis memuru.","e2":"He has a burly build.","e2t":"Yapılı bir fiziği var."},{"w":"bustle","tr":"koşuşturmak / hareketlilik / canlılık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To do things in a hurried and busy way","dt":"Acele ve meşgul bir şekilde bir şeyler yapmak","e1":"The city was bustling with activity.","e1t":"Şehir hareketlilikle (faaliyetle) kaynıyordu.","e2":"The hustle and bustle of city life.","e2t":"Şehir hayatının keşmekeşi ve hareketliliği."},{"w":"buttress","tr":"desteklemek / payanda / güçlendirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To build a structure to support a wall; or to support an argument","dt":"Bir duvarı desteklemek için yapı inşa etmek; veya bir iddiayı desteklemek","e1":"To buttress an argument with facts.","e1t":"Bir iddiayı gerçeklerle desteklemek.","e2":"The stone buttresses of the cathedral.","e2t":"Katedralin taş payandaları."},{"w":"candid","tr":"açık sözlü / içten / hazırlıksız (fotoğraf)","te":"Adjective","tt":"Sıfat","de":"Honest and telling the truth, especially about something difficult","dt":"Özellikle zor bir konuda dürüst ve gerçekleri söyleyen","e1":"A candid discussion.","e1t":"İçten (açık) bir tartışma.","e2":"To be candid with someone.","e2t":"Birine karşı açık sözlü olmak."},{"w":"candor","tr":"dürüstlük / açıklık","te":"Noun","tt":"İsim","de":"The quality of being open and honest in expression; frankness","dt":"İfadede açık ve dürüst olma niteliği; içtenlik","e1":"I appreciate your candor in this matter.","e1t":"Bu konudaki dürüstlüğünü takdir ediyorum.","e2":"With total candor.","e2t":"Tüm açıklığıyla."},{"w":"canine","tr":"köpeğe ait / köpek dişi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to dogs; or one of the four pointed teeth","dt":"Köpeklerle ilgili; veya köpek dişi","e1":"Canine behavior.","e1t":"Köpek davranışı.","e2":"Canine teeth.","e2t":"Köpek dişleri."},{"w":"capacious","tr":"geniş / ferah / çok alanlı","te":"Adjective","tt":"Sıfat","de":"Having a lot of space inside","dt":"İçinde çok fazla alan (boşluk) olan","e1":"A capacious bag.","e1t":"Geniş (her şeyi alan) bir çanta.","e2":"A capacious memory.","e2t":"Engin (güçlü) bir hafıza."},{"w":"capitulate","tr":"teslim olmak / boyun eğmek","te":"Verb","tt":"Fiil","de":"To accept something or stop resisting","dt":"Bir şeyi kabul etmek veya direnmeyi bırakmak","e1":"The enemy finally capitulated.","e1t":"Düşman sonunda teslim oldu.","e2":"To capitulate to the protesters' demands.","e2t":"Protestocuların taleplerine boyun eğmek."},{"w":"capricious","tr":"değişken / maymun iştahlı / keyfi","te":"Adjective","tt":"Sıfat","de":"Changing mood or behavior suddenly and unexpectedly","dt":"Ruh halini veya davranışını aniden ve beklenmedik şekilde değiştiren","e1":"Capricious weather.","e1t":"Değişken hava.","e2":"A capricious boss.","e2t":"Sağı solu belli olmayan (keyfi davranan) bir patron."},{"w":"carcass","tr":"hayvan leşi / gövde (kasaplık)","te":"Noun","tt":"İsim","de":"The body of a dead animal","dt":"Ölü bir hayvanın vücudu","e1":"Vultures gathered around the carcass.","e1t":"Akbabalar leşin etrafında toplandı.","e2":"The carcass of a burnt","e2t":"out car."},{"w":"cardinal","tr":"temel / ana / baş / kardinal","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Most important; or a high","dt":"ranking priest","e1":"En önemli; veya yüksek rütbeli rahip","e1t":"A cardinal rule.","e2":"Temel (en önemli) kural.","e2t":"Of cardinal importance."},{"w":"caress","tr":"okşamak / şefkatle dokunmak / okşayış","te":"Verb/Noun","tt":"Fiil/İsim","de":"To touch someone gently and lovingly","dt":"Birine nazikçe ve sevgiyle dokunmak","e1":"She gently caressed the baby's cheek.","e1t":"Bebeğin yanağını nazikçe okşadı.","e2":"The breeze caressed her face.","e2t":"Meltem yüzünü okşadı."},{"w":"caricature","tr":"karikatürleştirmek / alaycı tasvir","te":"Noun/Verb","tt":"İsim/Fiil","de":"A drawing or description that makes someone look funny","dt":"Birini komik gösteren çizim veya betimleme","e1":"A cruel caricature of the politician.","e1t":"Siyasetçinin zalimce bir karikatürü.","e2":"His performance was a caricature of a real spy.","e2t":"Performansı gerçek bir casusun karikatürü (abartılı taklidi) gibiydi."},{"w":"carnivorous","tr":"etçil / etobur","te":"Adjective","tt":"Sıfat","de":"(Of an animal) eating meat","dt":"(Hayvan için) et yiyen","e1":"Carnivorous plants.","e1t":"Etçil bitkiler.","e2":"Lions are carnivorous animals.","e2t":"Aslanlar etçil hayvanlardır."},{"w":"castigate","tr":"cezalandırmak / sertçe eleştirmek","te":"Verb","tt":"Fiil","de":"To criticize someone severely","dt":"Birini çok sert bir şekilde eleştirmek","e1":"He was castigated for his mistakes.","e1t":"Hatalarından dolayı sertçe eleştirildi (yerildi).","e2":"The report castigated the government.","e2t":"Rapor hükümeti sert dille eleştirdi."},{"w":"categorical","tr":"açık ve kesin / mutlak","te":"Adjective","tt":"Sıfat","de":"(Of a statement) without any doubt or possibility of being wrong","dt":"(Beyan için) şüpheye yer bırakmayan veya hatasız","e1":"A categorical denial.","e1t":"Kesin bir reddediş.","e2":"He was categorical in his refusal.","e2t":"Reddi konusunda çok net ve kesindi."},{"w":"caustic","tr":"yakıcı / iğneleyici / aşındırıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to burn skin; or (of remarks) bitter and sarcastic","dt":"Cildi yakabilen; veya (söz için) acı ve iğneleyici","e1":"Caustic soda.","e1t":"Kostik soda (yakıcı madde).","e2":"A caustic remark.","e2t":"İğneleyici (yakıcı) bir söz."},{"w":"cavernous","tr":"geniş ve derin / oyuk gibi","te":"Adjective","tt":"Sıfat","de":"Like a large cave in size or shape","dt":"Boyut veya şekil olarak büyük bir mağara gibi","e1":"A cavernous hallway.","e1t":"Geniş ve derin (boşluk hissi veren) bir koridor.","e2":"His cavernous voice.","e2t":"Derinden gelen (tok) sesi."},{"w":"ceasefire","tr":"ateşkes","te":"Noun","tt":"İsim","de":"An agreement to stop fighting for a period of time","dt":"Bir süreliğine savaşmayı durdurma anlaşması","e1":"To call a ceasefire.","e1t":"Ateşkes ilan etmek.","e2":"Ceasefire agreement.","e2t":"Ateşkes anlaşması."},{"w":"celestial","tr":"göksel / gökyüzüne ait / kutsal","te":"Adjective","tt":"Sıfat","de":"Relating to the sky or outer space","dt":"Gökyüzü veya uzay ile ilgili","e1":"Celestial bodies (stars, planets).","e1t":"Gök cisimleri.","e2":"Celestial music (heavenly).","e2t":"Ulvi (cennet gibi) müzik."},{"w":"censor","tr":"sansürlemek / sansür memuru","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove parts of a book or movie that are offensive","dt":"Bir kitap veya filmin sakıncalı kısımlarını çıkarmak","e1":"The movie was censored for violence.","e1t":"Film şiddet içerdiği için sansürlendi.","e2":"Press censor.","e2t":"Basın sansür memuru."},{"w":"censure","tr":"kınamak / eleştirmek / kınama","te":"Verb/Noun","tt":"Fiil/İsim","de":"Strong official criticism of someone","dt":"Birine yönelik güçlü resmi eleştiri","e1":"The minister faced a vote of censure.","e1t":"Bakan kınama oylamasıyla karşı karşıya kaldı.","e2":"He was censured for his conduct.","e2t":"Davranışlarından dolayı kınandı."},{"w":"ceremonial","tr":"törensel / resmi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a formal ceremony","dt":"Resmi bir törenle ilgili","e1":"A ceremonial occasion.","e1t":"Törensel (resmi) bir durum.","e2":"Ceremonial dress.","e2t":"Tören kıyafeti."},{"w":"chagrin","tr":"hayal kırıklığı / üzüntü / mahcubiyet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of disappointment or annoyance caused by failure","dt":"Başarısızlığın neden olduğu hayal kırıklığı veya huzursuzluk hissi","e1":"Much to his chagrin, he lost the race.","e1t":"Büyük hayal kırıklığına uğrayarak yarışı kaybetti.","e2":"To be chagrined at the results.","e2t":"Sonuçlar karşısında mahcup olmak (üzülmek)."},{"w":"chaotic","tr":"kaotik / karmaşık / darmadağın","te":"Adjective","tt":"Sıfat","de":"In a state of complete confusion and lack of order","dt":"Tam bir karmaşa ve düzensizlik içinde","e1":"A chaotic situation.","e1t":"Kaotik bir durum.","e2":"The traffic in the city is chaotic.","e2t":"Şehirdeki trafik darmadağın (karmaşık)."},{"w":"charismatic","tr":"karizmatik / etkileyici","te":"Adjective","tt":"Sıfat","de":"Having a personal quality that attracts and influences people","dt":"İnsanları çeken ve etkileyen bir kişisel özelliğe sahip olan","e1":"A charismatic leader.","e1t":"Karizmatik bir lider.","e2":"He is very charismatic.","e2t":"O çok karizmatiktir."},{"w":"charitable","tr":"hayırsever / yardımsever / hoşgörülü","te":"Adjective","tt":"Sıfat","de":"Giving money or food to help poor people; or kind in judging","dt":"Fakirlere yardım eden; veya yargılarken nazik (hoşgörülü) olan","e1":"A charitable foundation.","e1t":"Yardım vakfı.","e2":"To be charitable toward his mistakes.","e2t":"Onun hatalarına karşı hoşgörülü olmak."},{"w":"chasm","tr":"büyük uçurum / derin ayrılık / yarık","te":"Noun","tt":"İsim","de":"A very deep narrow opening in rock; or a big difference","dt":"Kayadaki çok derin dar açıklık; veya büyük fark (ayrılık)","e1":"A deep chasm in the ice.","e1t":"Buzda derin bir yarık.","e2":"The chasm between the rich and the poor.","e2t":"Zengin ve fakir arasındaki derin uçurum (fark)."},{"w":"chauvinistic","tr":"aşırı milliyetçi / şovenist","te":"Adjective","tt":"Sıfat","de":"Believing that your own country or sex is better than others","dt":"Kendi ülkesinin veya cinsiyetinin diğerlerinden daha iyi olduğuna inanan","e1":"Chauvinistic attitudes.","e1t":"Şovenist tutumlar.","e2":"Male chauvinistic (believing men are superior).","e2t":"Erkek şovenizmi (erkek üstünlüğüne inanma)."},{"w":"chide","tr":"azarlamak / çıkışmak","te":"Verb","tt":"Fiil","de":"To speak to someone severely because they have behaved badly","dt":"Kötü davrandıkları için birine sertçe konuşmak (azarlamak)","e1":"She chided him for his laziness.","e1t":"Tembelliğinden dolayı ona çıkıştı (azarladı).","e2":"To chide someone gently.","e2t":"Birini nazikçe ikaz etmek."},{"w":"chuckle","tr":"kıkırdamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh quietly or inwardly","dt":"Kendi kendine veya sessizce gülmek","e1":"He chuckled at the memory of the joke.","e1t":"Şakanın hatırasına kıkırdadı.","e2":"A quiet chuckle.","e2t":"Sessiz bir kıkırdama."},{"w":"clairvoyant","tr":"durugörücü / kahin / gaipten haber veren","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who says they can see the future or things others cannot","dt":"Geleceği veya başkalarının göremediği şeyleri gördüğünü söyleyen kişi","e1":"She went to see a clairvoyant.","e1t":"Bir durugörücüye (medyuma) gitti.","e2":"Clairvoyant powers.","e2t":"Kahinlik güçleri."},{"w":"clandestine","tr":"gizli / saklı / el altından","te":"Adjective","tt":"Sıfat","de":"Planned or done in secret","dt":"Gizli planlanan veya yapılan","e1":"A clandestine meeting.","e1t":"Gizli bir toplantı.","e2":"Clandestine activities.","e2t":"Gizli (yeraltı) faaliyetler."},{"w":"clarity","tr":"açıklık / netlik / berraklık","te":"Noun","tt":"İsim","de":"The quality of being clear and easy to understand or see","dt":"Net ve anlaşılması veya görülmesi kolay olma niteliği","e1":"Clarity of vision.","e1t":"Görüş netliği.","e2":"Lack of clarity in the explanation.","e2t":"Açıklamadaki netlik eksikliği."},{"w":"clientele","tr":"müşteri kitlesi / müdavimler","te":"Noun","tt":"İsim","de":"All the people who regularly use a shop, hotel, or lawyer","dt":"Bir dükkan, otel veya avukatı düzenli kullanan tüm insanlar","e1":"A wealthy clientele.","e1t":"Zengin bir müşteri kitlesi.","e2":"To attract a younger clientele.","e2t":"Daha genç bir müşteri kitlesini çekmek."},{"w":"clinch","tr":"kesinleştirmek / perçinlemek / sarılmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To finally get or win something; or to settle an argument","dt":"Bir şeyi sonunda elde etmek veya kazanmak; veya bir tartışmayı sonuçlandırmak","e1":"To clinch a deal.","e1t":"Bir anlaşmayı kesinleştirmek (bağlamak).","e2":"That argument clinched it for me.","e2t":"Bu iddia benim için konuyu netleştirdi (ikna etti)."},{"w":"coax","tr":"ikna etmek / razı etmek (tatlı dille)","te":"Verb","tt":"Fiil","de":"To persuade someone gradually or by flattery","dt":"Birini yavaşça veya dalkavuklukla ikna etmek","e1":"She coaxed the cat out from under the car.","e1t":"Kediyi arabanın altından çıkması için tatlı dille ikna etti.","e2":"Coax someone into doing...","e2t":"Birini bir şey yapmaya razı etmek."},{"w":"coerce","tr":"zorlamak / baskı yapmak","te":"Verb","tt":"Fiil","de":"To force someone to do something they do not want to do","dt":"Birini istemediği bir şeyi yapmaya zorlamak","e1":"To coerce someone into signing a contract.","e1t":"Birini sözleşme imzalamaya zorlamak.","e2":"Coerced confession.","e2t":"Baskı altında (zorla) alınan itiraf."},{"w":"cognition","tr":"biliş / kavrama","te":"Noun","tt":"İsim","de":"The process of getting knowledge by thought or experience","dt":"Düşünce veya deneyim yoluyla bilgi edinme süreci","e1":"Child cognition.","e1t":"Çocuk bilişi.","e2":"Cognitive development.","e2t":"Bilişsel gelişim."},{"w":"coincide","tr":"aynı zamana denk gelmek / örtüşmek","te":"Verb","tt":"Fiil","de":"To happen at the same time; or to be the same","dt":"Aynı anda gerçekleşmek; veya aynı (örtüşen) olmak","e1":"My holiday coincides with yours.","e1t":"Tatilim seninkiyle aynı zamana denk geliyor.","e2":"Our views coincide on this issue.","e2t":"Bu konuda görüşlerimiz örtüşüyor."},{"w":"collateral","tr":"teminat / yan / ikincil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Property that is used to guarantee a loan; or secondary","dt":"Bir krediyi garanti altına almak için kullanılan mülk (teminat); veya ikincil","e1":"To use your house as collateral for a loan.","e1t":"Evini kredi için teminat olarak kullanmak.","e2":"Collateral damage (unintended).","e2t":"İkincil (istenmeyen) hasar."},{"w":"colloquial","tr":"günlük dil / konuşma diline ait","te":"Adjective","tt":"Sıfat","de":"(Of words) used in informal conversation rather than in writing","dt":"(Kelimeler için) yazılıdan ziyade resmi olmayan konuşmada kullanılan","e1":"Colloquial language.","e1t":"Günlük konuşma dili.","e2":"Colloquialisms.","e2t":"Konuşma diline özgü ifadeler."},{"w":"colossal","tr":"kocaman / devasa / muazzam","te":"Adjective","tt":"Sıfat","de":"Extremely large","dt":"Son derece büyük","e1":"A colossal waste of time.","e1t":"Muazzam bir zaman kaybı.","e2":"The project was a colossal failure.","e2t":"Proje devasa bir başarısızlıktı."},{"w":"combustion","tr":"yanma / tutuşma","te":"Noun","tt":"İsim","de":"The chemical process of burning","dt":"Yanma kimyasal süreci","e1":"Internal combustion engine.","e1t":"İçten yanmalı motor.","e2":"Spontaneous combustion.","e2t":"Kendiliğinden yanma."},{"w":"commend","tr":"övmek / takdir etmek / emanet etmek","te":"Verb","tt":"Fiil","de":"To praise someone or something publicly","dt":"Birini veya bir şeyi herkesin önünde övmek","e1":"I commend you for your courage.","e1t":"Cesaretinden dolayı seni takdir ediyorum.","e2":"His designs are to be highly commended.","e2t":"Tasarımları büyük övgüyü hak ediyor."},{"w":"commiserate","tr":"acısını paylaşmak / teselli etmek","te":"Verb","tt":"Fiil","de":"To express sympathy for someone's unhappiness","dt":"Birinin mutsuzluğuna sempati (taziye) göstermek","e1":"I commiserated with her on the loss of her job.","e1t":"İşini kaybettiği için onunla dertleştim (acısını paylaştım).","e2":"","e2t":""},{"w":"compelling","tr":"ikna edici / sürükleyici / zorunlu","te":"Adjective","tt":"Sıfat","de":"Very exciting or convincing","dt":"Çok heyecan verici veya ikna edici","e1":"A compelling argument.","e1t":"İkna edici bir iddia.","e2":"Compelling evidence.","e2t":"Zorlayıcı (güçlü) kanıt."},{"w":"complacent","tr":"kendine fazla güvenen / halinden memnun (tehlikeli)","te":"Adjective","tt":"Sıfat","de":"Feeling too satisfied with yourself to the point of not trying harder","dt":"Daha fazla çabalamaya gerek duymayacak kadar kendinden memnun","e1":"We cannot afford to become complacent about safety.","e1t":"Güvenlik konusunda rehavete kapılma (fazla güvenme) lüksümüz yok.","e2":"","e2t":""},{"w":"compliant","tr":"uyumlu / uysal / şartlara uygun","te":"Adjective","tt":"Sıfat","de":"Willing to do what other people want you to do","dt":"Diğer insanların istediklerini yapmaya istekli","e1":"A compliant child.","e1t":"Söz dinleyen (uysal) bir çocuk.","e2":"The company is fully compliant with tax laws.","e2t":"Şirket vergi kanunlarına tam uyumludur."},{"w":"composed","tr":"sakin / kendine hakim / bestelenmiş","te":"Adjective","tt":"Sıfat","de":"Calm and in control of your emotions","dt":"Sakin ve duygularına hakim","e1":"She looked remarkably composed throughout the crisis.","e1t":"Kriz boyunca dikkat çekici derecede sakin görünüyordu.","e2":"Composed of (consisting of).","e2t":"..."},{"w":"comprehension","tr":"kavrama / anlama / idrak","te":"Noun","tt":"İsim","de":"The ability to understand something","dt":"Bir şeyi anlama yeteneği","e1":"Reading comprehension.","e1t":"Okuduğunu anlama.","e2":"The problem is beyond my comprehension.","e2t":"Sorun benim anlayışımın (idrakimin) ötesinde."},{"w":"compulsion","tr":"zorlayıcı istek / dürtü / zorlama","te":"Noun","tt":"İsim","de":"A very strong wish to do something","dt":"Bir şeyi yapmaya yönelik çok güçlü (bazen mantıksız) istek","e1":"He felt a compulsion to tell the truth.","e1t":"Doğruyu söylemek için bir dürtü hissetti.","e2":"To act under compulsion.","e2t":"Baskı (zorlama) altında hareket etmek."},{"w":"conceited","tr":"kibirli / kendini beğenmiş","te":"Adjective","tt":"Sıfat","de":"Too proud of yourself and your actions","dt":"Kendisiyle ve yaptıklarıyla aşırı gurur duyan","e1":"A conceited young man.","e1t":"Kibirli genç bir adam.","e2":"I don't want to sound conceited, but...","e2t":"Kibirli görünmek istemem ama..."},{"w":"concoct","tr":"uydurmak / tezgahlamak / hazırlamak (karışım)","te":"Verb","tt":"Fiil","de":"To invent a story or plan; or to prepare a mixture","dt":"Bir hikaye veya plan icat etmek; veya bir karışım hazırlamak","e1":"He concocted an elaborate excuse for being late.","e1t":"Geç kalmak için detaylı bir bahane uydurdu.","e2":"To concoct a new drink.","e2t":"Yeni bir içecek hazırlamak."},{"w":"condense","tr":"yoğunlaştırmak / özetlemek / sıvılaşmak","te":"Verb","tt":"Fiil","de":"To make something shorter; or to change gas to liquid","dt":"Bir şeyi kısaltmak; veya gazı sıvıya dönüştürmek","e1":"To condense a long report into a few pages.","e1t":"Uzun bir raporu birkaç sayfaya özetlemek.","e2":"Water vapor condenses to form clouds.","e2t":"Su buharı yoğunlaşarak bulutları oluşturur."},{"w":"condescending","tr":"tepeden bakan / küçümseyen","te":"Adjective","tt":"Sıfat","de":"Treating someone as if you are more important or intelligent than them","dt":"Birine kendinden daha az önemliymiş gibi davranan","e1":"I hate the way he speaks to me in that condescending tone.","e1t":"Bana o küçümseyen tonda konuşmasından nefret ediyorum.","e2":"","e2t":""},{"w":"condone","tr":"görmezden gelmek / göz yummak / affetmek","te":"Verb","tt":"Fiil","de":"To ignore or accept behavior that is wrong","dt":"Yanlış olan bir davranışı görmezden gelmek veya kabul etmek","e1":"We cannot condone violence in any form.","e1t":"Şiddetin hiçbir formuna göz yumamayız.","e2":"The government condoned the illegal activities.","e2t":"Hükümet yasadışı faaliyetleri görmezden geldi."},{"w":"conducive","tr":"uygun / elverişli / yardımcı","te":"Adjective","tt":"Sıfat","de":"Providing the right conditions for something to happen","dt":"Bir şeyin gerçekleşmesi için doğru koşulları sağlayan","e1":"A quiet environment is conducive to study.","e1t":"Sessiz bir ortam ders çalışmak için elverişlidir.","e2":"Conducive to health.","e2t":"Sağlığa yardımcı."},{"w":"confectionery","tr":"şekerleme ürünleri / şekerlemecilik","te":"Noun","tt":"İsim","de":"Sweets, chocolates, and similar food","dt":"Şekerlemeler, çikolatalar ve benzeri gıdalar","e1":"A confectionery shop.","e1t":"Şekerlemeci.","e2":"The confectionery industry.","e2t":"Şekerleme endüstrisi."},{"w":"confederation","tr":"birlik / konfederasyon / ittifak","te":"Noun","tt":"İsim","de":"An organization consisting of groups that have joined together","dt":"Bir araya gelmiş gruplardan oluşan organizasyon","e1":"The Confederation of British Industry.","e1t":"İngiliz Sanayi Konfederasyonu.","e2":"A confederation of independent states.","e2t":"Bağımsız devletler birliği."},{"w":"confer","tr":"görüşmek / danışmak / (unvan vb.) vermek","te":"Verb","tt":"Fiil","de":"To discuss something with other people; or to give an honor","dt":"Diğer insanlarla bir konuyu tartışmak; veya bir onur (unvan) vermek","e1":"I need to confer with my lawyer.","e1t":"Avukatıma danışmam gerekiyor.","e2":"An honorary degree was conferred on him.","e2t":"Ona fahri doktora unvanı verildi."},{"w":"confidant","tr":"sırdaş / yakın dost","te":"Noun","tt":"İsim","de":"A person you trust and share your secrets with","dt":"Güvendiğiniz ve sırlarınızı paylaştığınız kişi","e1":"He is my closest confidant.","e1t":"O benim en yakın sırdaşımdır.","e2":"A female confidante.","e2t":"Kadın sırdaş."},{"w":"confinement","tr":"kapatma / hapis / tecrit / doğum","te":"Noun","tt":"İsim","de":"The state of being kept in a closed place","dt":"Kapalı bir yerde tutulma durumu","e1":"Solitary confinement.","e1t":"Hücre hapsi (tecrit).","e2":"Confinement to a wheelchair.","e2t":"Tekerlekli sandalyeye mahkum olma."},{"w":"confluence","tr":"birleşme / kavşak / akışma","te":"Noun","tt":"İsim","de":"The place where two rivers flow together; or a coming together","dt":"İki nehrin birleştiği yer; veya bir araya gelme","e1":"The confluence of two great cultures.","e1t":"İki büyük kültürün birleşimi.","e2":"At the confluence of the rivers.","e2t":"Nehirlerin birleştiği noktada."},{"w":"conformity","tr":"uyma / uygunluk / boyun eğme","te":"Noun","tt":"İsim","de":"Behavior that follows the usual standards or rules","dt":"Olağan standartları veya kuralları takip eden davranış","e1":"Conformity to social norms.","e1t":"Sosyal normlara uyum.","e2":"To act in conformity with the law.","e2t":"Yasaya uygun olarak hareket etmek."},{"w":"confound","tr":"şaşırtmak / altüst etmek / karıştırmak","te":"Verb","tt":"Fiil","de":"To confuse and surprise someone","dt":"Birini şaşırtmak ve kafasını karıştırmak","e1":"The results of the study confounded the experts.","e1t":"Çalışmanın sonuçları uzmanları şaşırttı.","e2":"To confound the enemy.","e2t":"Düşmanı şaşırtmak (planlarını bozmak)."},{"w":"confrontational","tr":"çatışmacı / kavgacı","te":"Adjective","tt":"Sıfat","de":"Intentionally causing arguments or conflict","dt":"Kasten tartışmaya veya çatışmaya neden olan","e1":"He has a very confrontational approach to management.","e1t":"Yönetim konusunda çok çatışmacı bir yaklaşımı var.","e2":"A confrontational tone.","e2t":"Kavgacı bir ton."},{"w":"congenial","tr":"hoş / uyumlu / cana yakın / kafa dengi","te":"Adjective","tt":"Sıfat","de":"Pleasant and friendly; or having similar interests","dt":"Hoş ve dostça; veya benzer ilgi alanlarına sahip","e1":"A congenial working environment.","e1t":"Hoş (uyumlu) bir çalışma ortamı.","e2":"We are congenial spirits.","e2t":"Kafa dengiyiz."},{"w":"conglomerate","tr":"kümelenmek / şirket grubu / konglomera","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very large company formed from many smaller ones","dt":"Birçok küçük şirketin birleşmesiyle oluşan dev şirket","e1":"A media conglomerate.","e1t":"Medya grubu (dev şirketi).","e2":"Rocks conglomerate over time.","e2t":"Kayalar zamanla kümelenir (birleşir)."},{"w":"conjecture","tr":"varsayım / tahmin / tahminde bulunmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A guess that is based on information that is not complete","dt":"Tam olmayan bilgilere dayanan tahmin","e1":"That is mere conjecture.","e1t":"Bu sadece bir varsayımdan ibaret.","e2":"We can only conjecture the cause.","e2t":"Nedeni hakkında sadece tahminde bulunabiliriz."},{"w":"conjure","tr":"çağrıştırmak / büyü yapmak / hokkabazlık yapmak","te":"Verb","tt":"Fiil","de":"To make something appear or to bring a picture to mind","dt":"Bir şeyi ortaya çıkarmak veya zihne bir resim getirmek","e1":"The smell of rain conjures up memories of my childhood.","e1t":"Yağmur kokusu çocukluk anılarımı çağrıştırıyor.","e2":"To conjure a rabbit out of a hat.","e2t":"Şapkadan tavşan çıkarmak."},{"w":"conscientious","tr":"vicdanlı / titiz / işine bağlı","te":"Adjective","tt":"Sıfat","de":"Putting a lot of effort into your work; doing what is right","dt":"İşine çok çaba sarf eden; doğru olanı yapan","e1":"A conscientious student.","e1t":"Titiz (çalışkan) bir öğrenci.","e2":"He is very conscientious about his duties.","e2t":"Görevleri konusunda çok vicdanlıdır."},{"w":"consecrate","tr":"kutsamak / adamak","te":"Verb","tt":"Fiil","de":"To officially state that a place or thing is holy","dt":"Bir yerin veya şeyin kutsal olduğunu resmi olarak bildirmek","e1":"The church was consecrated in 1850.","e1t":"Kilise 1850'de kutsandı.","e2":"To consecrate your life to God.","e2t":"Hayatını Tanrı'ya adamak."},{"w":"consequential","tr":"önemli / sonuç olarak ortaya çıkan","te":"Adjective","tt":"Sıfat","de":"Important; or happening as a result of something","dt":"Önemli; veya bir şeyin sonucu olarak gerçekleşen","e1":"A consequential decision.","e1t":"Önemli (etkili) bir karar.","e2":"These risks are not consequential.","e2t":"Bu riskler kayda değer değil."},{"w":"conservatory","tr":"konservatuvar / camdan ek oda (sera)","te":"Noun","tt":"İsim","de":"A school for music; or a room with glass walls for plants","dt":"Müzik okulu; veya bitkiler için cam duvarlı oda","e1":"To study piano at the conservatory.","e1t":"Konservatuvarda piyano okumak.","e2":"We had tea in the conservatory.","e2t":"Limonlukta (cam odada) çay içtik."},{"w":"consign","tr":"teslim etmek / havale etmek / göndermek","te":"Verb","tt":"Fiil","de":"To give or send something to someone officially","dt":"Bir şeyi birine resmi olarak vermek veya göndermek","e1":"The goods have been consigned to you.","e1t":"Mallar size sevk edildi (teslim edildi).","e2":"To consign something to the waste basket.","e2t":"Bir şeyi çöp kutusuna (havale etmek) atmak."},{"w":"console","tr":"teselli etmek / avutmak / konsol (kumanda)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make someone feel better when they are sad; or a panel","dt":"Biri üzgün olduğunda daha iyi hissetmesini sağlamak; veya panel","e1":"I tried to console her after her cat died.","e1t":"Kedisi öldükten sonra onu teselli etmeye çalıştım.","e2":"A mixing console.","e2t":"Mikser (ses kontrol) paneli."},{"w":"constituent","tr":"bileşen / kurucu / seçmen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"One of the parts that make up something; or a voter","dt":"Bir şeyi oluşturan parçalardan biri; veya seçmen","e1":"Vitamins are natural constituents of food.","e1t":"Vitaminler gıdaların doğal bileşenleridir.","e2":"She wrote a letter to her constituents.","e2t":"Seçmenlerine bir mektup yazdı."},{"w":"constrict","tr":"sıkmak / daraltmak / kısıtlamak","te":"Verb","tt":"Fiil","de":"To become narrower or tighter; or to limit someone","dt":"Daha dar veya sıkı hale gelmek; veya birini sınırlamak","e1":"Cold weather causes blood vessels to constrict.","e1t":"Soğuk hava kan damarlarının daralmasına (büzülmesine) neden olur.","e2":"Regulations that constrict the economy.","e2t":"Ekonomiyi kısıtlayan düzenlemeler."},{"w":"constructively","tr":"yapıcı şekilde","te":"Adverb","tt":"Zarf","de":"In a way that is useful and intended to help or improve","dt":"Faydalı ve geliştirmeyi amaçlayan bir şekilde","e1":"To use your time constructively.","e1t":"Zamanını yapıcı şekilde kullanmak.","e2":"To deal with criticism constructively.","e2t":"Eleştirileri yapıcı bir şekilde ele almak."},{"w":"construe","tr":"yorumlamak / anlam çıkarmak","te":"Verb","tt":"Fiil","de":"To understand the meaning of something in a particular way","dt":"Bir şeyin anlamını belirli bir şekilde anlamak (yorumlamak)","e1":"Her silence was construed as agreement.","e1t":"Sessizliği anlaşma (onay) olarak yorumlandı.","e2":"How do you construe this rule?","e2t":"Bu kuralı nasıl yorumluyorsunuz?"},{"w":"consummate","tr":"mükemmel / usta / tamamlamak (evliliği)","te":"Adjective/Verb","tt":"Perfect or highly skilled; or to make complete","de":"Mükemmel veya çok yetenekli; veya tamamlamak","dt":"A consummate professional.","e1":"Tam bir (mükemmel) profesyonel.","e1t":"To consummate a marriage.","e2":"Evliliği fiilen tamamlamak.","e2t":""},{"w":"contagion","tr":"bulaşma / salgın / kötü etki","te":"Noun","tt":"İsim","de":"The spread of a disease; or the spread of a feeling","dt":"Bir hastalığın yayılması; veya bir duygunun yayılması","e1":"To prevent the contagion from spreading.","e1t":"Salgının yayılmasını önlemek.","e2":"Financial contagion.","e2t":"Finansal krizin yayılması (bulaşması)."},{"w":"contaminate","tr":"kirletmek / bulaştırmak / bozmak","te":"Verb","tt":"Fiil","de":"To make something poisonous or dirty","dt":"Bir şeyi zehirli veya kirli hale getirmek","e1":"The river was contaminated with chemicals.","e1t":"Nehir kimyasallarla kirlendi.","e2":"Contaminated blood.","e2t":"Bulaşlı (kirli) kan."},{"w":"contempt","tr":"küçümsüme / aşağılama / hakaret (mahkeme)","te":"Noun","tt":"İsim","de":"A strong feeling of lack of respect","dt":"Güçlü bir saygısızlık hissi","e1":"To show contempt for authority.","e1t":"Otoriteye karşı küçümseme (saygısızlık) göstermek.","e2":"Contempt of court.","e2t":"Mahkemeye hakaret."},{"w":"contentious","tr":"tartışmalı / kavgacı","te":"Adjective","tt":"Sıfat","de":"Causing or likely to cause an argument","dt":"Tartışmaya neden olan veya olması muhtemel olan","e1":"A contentious issue.","e1t":"Tartışmalı bir konu.","e2":"He is a very contentious person.","e2t":"Çok kavgacı (hırçın) biridir."},{"w":"contraband","tr":"kaçak mal / kaçakçılık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Goods that are brought into a country illegally","dt":"Bir ülkeye yasadışı yollarla sokulan mallar","e1":"To seize contraband goods.","e1t":"Kaçak mallara el koymak.","e2":"Contraband tobacco.","e2t":"Kaçak tütün."},{"w":"contravene","tr":"ihlal etmek / karşı gelmek","te":"Verb","tt":"Fiil","de":"To do something that is not allowed by a law or rule","dt":"Yasaya veya kurala izin verilmeyen bir şeyi yapmak","e1":"To contravene safety regulations.","e1t":"Güvenlik düzenlemelerini ihlal etmek.","e2":"His actions contravene the policy.","e2t":"Eylemleri politikaya aykırıdır."},{"w":"contrite","tr":"pişman / suçluluk duyan","te":"Adjective","tt":"Sıfat","de":"Feeling very sorry and guilty for something bad you have done","dt":"Yapılan kötü bir şey için çok üzgün ve suçlu hisseden","e1":"He looked genuinely contrite.","e1t":"Gerçekten pişman görünüyordu.","e2":"A contrite apology.","e2t":"Pişmanlık dolu bir özür."},{"w":"contrive","tr":"icat etmek / plan yapmak / becermek (zorla)","te":"Verb","tt":"Fiil","de":"To arrange a situation or invent a device cleverly","dt":"Bir durumu ayarlamak veya zekice bir cihaz icat etmek","e1":"To contrive a meeting.","e1t":"Bir buluşma ayarlamak (tezgahlamak).","e2":"She contrived to spend as little money as possible.","e2t":"Mümkün olduğunca az para harcamayı becerdi."},{"w":"convene","tr":"toplamak / toplanmak / toplantıya çağırmak","te":"Verb","tt":"Fiil","de":"To bring people together for a formal meeting","dt":"İnsanları resmi bir toplantı için bir araya getirmek","e1":"The committee will convene tomorrow.","e1t":"Komite yarın toplanacak.","e2":"To convene a peace conference.","e2t":"Bir barış konferansı düzenlemek (toplamak)."},{"w":"conversely","tr":"tersine / aksine","te":"Adverb","tt":"Zarf","de":"In an opposite way","dt":"Zıt bir şekilde","e1":"He was very tall; conversely, his brother was quite short.","e1t":"Çok uzundu; tersine, kardeşi oldukça kısaydı.","e2":"You can add sugar, or conversely, use honey.","e2t":"Şeker ekleyebilirsiniz veya aksine bal kullanabilirsiniz."},{"w":"convivial","tr":"neşeli / şen / dostane","te":"Adjective","tt":"Sıfat","de":"Friendly and making you feel welcome and happy","dt":"Dostça ve sizi mutlu, hoş karşılanmış hissettiren","e1":"A convivial atmosphere.","e1t":"Neşeli (keyifli) bir atmosfer.","e2":"A convivial host.","e2t":"Şen şakrak (cana yakın) bir ev sahibi."},{"w":"convulse","tr":"sarsılmak / titremek / kıvranmak","te":"Verb","tt":"Fiil","de":"To shake violently with sudden uncontrolled movements","dt":"Ani ve kontrolsüz hareketlerle şiddetle sarsılmak","e1":"She was convulsed with laughter.","e1t":"Gülmekten sarsıldı (kıvrandı).","e2":"The country was convulsed by civil war.","e2t":"Ülke iç savaşla sarsıldı."},{"w":"copious","tr":"bol / çok miktarda / bereketli","te":"Adjective","tt":"Sıfat","de":"Large in amount or quantity","dt":"Miktar veya sayıca çok fazla","e1":"She took copious notes during the lecture.","e1t":"Ders sırasında bol bol (çok miktarda) not aldı.","e2":"Copious amounts of food.","e2t":"Bol miktarda yemek."},{"w":"cordial","tr":"samimi / içten / nazik / şurup","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Friendly but formal and polite; or a sweet fruit drink","dt":"Dostça ama resmi ve nazik; veya tatlı meyve şurubu","e1":"A cordial welcome.","e1t":"Samimi bir karşılama.","e2":"Relations between the two countries are cordial.","e2t":"İki ülke arasındaki ilişkiler dostanedir (naziktir)."},{"w":"corroborate","tr":"doğrulamak / teyit etmek / desteklemek","te":"Verb","tt":"Fiil","de":"To add proof to an account, statement, or idea","dt":"Bir ifadeyi veya fikri kanıtlarla desteklemek","e1":"Recent research corroborates his theory.","e1t":"Son araştırmalar onun teorisini doğrulamaktadır.","e2":"The witness corroborated her story.","e2t":"Tanık onun hikayesini teyit etti."},{"w":"corrode","tr":"aşındırmak / paslanmak / kemirmek","te":"Verb","tt":"Fiil","de":"To slowly damage something by chemical action","dt":"Kimyasal etkiyle bir şeye yavaşça zarar vermek","e1":"Acid corrodes metal.","e1t":"Asit metali aşındırır.","e2":"Corruption corrodes the system.","e2t":"Yolsuzluk sistemi kemirir (aşındırır)."},{"w":"counterfeit","tr":"sahte / taklit / kalpazanlık yapmak","te":"Adjective/Noun/Verb","tt":"Made to look like the real thing in order to deceive","de":"Aldatmak amacıyla gerçeğine benzetilerek yapılmış","dt":"Counterfeit money.","e1":"Sahte para.","e1t":"Counterfeit designer bags.","e2":"Taklit marka çantalar.","e2t":""},{"w":"covenant","tr":"antlaşma / sözleşme / ahit","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal agreement or promise","dt":"Resmi bir anlaşma veya sözleşme","e1":"A restrictive covenant.","e1t":"Kısıtlayıcı sözleşme maddesi.","e2":"The Ten Commandments are part of the old covenant.","e2t":"On Emir eski ahdin bir parçasıdır."},{"w":"covert","tr":"gizli / örtülü / saklı","te":"Adjective","tt":"Sıfat","de":"Hidden or secret; not openly shown","dt":"Gizli veya saklı; açıkça gösterilmeyen","e1":"Covert operations.","e1t":"Gizli operasyonlar.","e2":"A covert glance.","e2t":"Gizli (çaktırmadan) bir bakış."},{"w":"covet","tr":"imrenmek / gözü kalmak / çok istemek","te":"Verb","tt":"Fiil","de":"To want to have something very much, especially something belonging to someone else","dt":"Bir şeye, özellikle başkasına ait olana çok sahip olmak istemek","e1":"She coveted her sister's success.","e1t":"Kız kardeşinin başarısına imrendi.","e2":"The coveted award.","e2t":"Herkesin arzuladığı (gözü kaldığı) ödül."},{"w":"cowardice","tr":"korkaklık","te":"Noun","tt":"İsim","de":"Lack of courage","dt":"Cesaret eksikliği","e1":"He was accused of cowardice in battle.","e1t":"Savaşta korkaklıkla suçlandı.","e2":"Moral cowardice.","e2t":"Ahlaki korkaklık."},{"w":"cower","tr":"büzülmek / sinmek / korkuyla eğilmek","te":"Verb","tt":"Fiil","de":"To lower your body because you are frightened","dt":"Korktuğunuz için vücudunuzu aşağı çekmek (büzülmek)","e1":"The dog cowered in the corner.","e1t":"Köpek köşeye sindi (büzüldü).","e2":"To cower in fear.","e2t":"Korkuyla büzülmek."},{"w":"coy","tr":"utangaç / çekingen / nazlı","te":"Adjective","tt":"Sıfat","de":"Intentionally keeping something secret or pretending to be shy","dt":"Kasten bir şeyi gizli tutan veya utangaçmış gibi davranan","e1":"She gave him a coy smile.","e1t":"Ona nazlı (çekingen) bir gülücük attı.","e2":"The government is being coy about its plans.","e2t":"Hükümet planları konusunda ketum (çekingen) davranıyor."},{"w":"crackdown","tr":"sıkı önlem / operasyon / yaptırım","te":"Noun","tt":"İsim","de":"A sudden strong effort to stop illegal activity","dt":"Yasadışı faaliyeti durdurmak için ani ve güçlü çaba","e1":"A crackdown on crime.","e1t":"Suça karşı sıkı önlem (operasyon).","e2":"A crackdown on tax evasion.","e2t":"Vergi kaçakçılığına karşı yaptırım."},{"w":"crafty","tr":"kurnaz / becerikli / hilekar","te":"Adjective","tt":"Sıfat","de":"Clever and good at getting what you want, often by deceiving","dt":"İstediğini elde etmede zeki ve (genellikle aldatarak) becerikli","e1":"A crafty politician.","e1t":"Kurnaz bir siyasetçi.","e2":"A crafty plan.","e2t":"Ustaca (kurnazca) hazırlanmış bir plan."},{"w":"crammed","tr":"tıka basa dolu / sıkış tıkış","te":"Adjective","tt":"Sıfat","de":"Very full of people or things","dt":"İnsan veya eşyayla çok dolu","e1":"The bus was crammed with people.","e1t":"Otobüs insanlarla tıka basa doluydu.","e2":"A desk crammed with papers.","e2t":"Kağıtlarla dolu (yığılı) bir masa."},{"w":"crass","tr":"kaba / düşüncesiz / ham","te":"Adjective","tt":"Sıfat","de":"Stupid and without considering how other people might feel","dt":"Aptalca ve başkalarının duygularını düşünmeden yapılan","e1":"A crass remark.","e1t":"Kaba (düşüncesizce) bir söz.","e2":"Crass materialism.","e2t":"Ham (yüzeysel) maddecilik."},{"w":"crave","tr":"can atmak / çok istemek / aşermek","te":"Verb","tt":"Fiil","de":"To have a very strong desire for something","dt":"Bir şeye karşı çok güçlü bir arzu duymak","e1":"To crave attention.","e1t":"İlgiye aç olmak (ilgi beklemek).","e2":"Pregnant women often crave certain foods.","e2t":"Hamile kadınlar genellikle bazı yiyeceklere aşerir (canı çeker)."},{"w":"crest","tr":"tepe noktası / zirve / arma / ibik","te":"Noun/Verb","tt":"İsim/Fiil","de":"The top part of a hill or wave; or a formal design","dt":"Bir tepenin veya dalganın en üst kısmı; veya resmi arma","e1":"The crest of a wave.","e1t":"Dalganın tepesi.","e2":"The family crest.","e2t":"Aile arması."},{"w":"crevice","tr":"çatlak / yarık","te":"Noun","tt":"İsim","de":"A small narrow crack in a rock or wall","dt":"Kaya veya duvardaki küçük dar çatlak","e1":"Small plants growing in the crevices.","e1t":"Çatlaklarda büyüyen küçük bitkiler.","e2":"To hide in a crevice.","e2t":"Bir yarığa saklanmak."},{"w":"cringe","tr":"utanmak / geri çekilmek / ezilip büzülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel embarrassed or to pull away in fear","dt":"Utanmak veya korkuyla geri çekilmek","e1":"I cringed when I saw my old photos.","e1t":"Eski fotoğraflarımı görünce utandım (yerin dibine girdim).","e2":"To cringe in pain.","e2t":"Acıyla büzülmek."},{"w":"crony","tr":"yakın arkadaş / kafadar (olumsuz anlamda)","te":"Noun","tt":"İsim","de":"A close friend, especially one who gets unfair advantages","dt":"Özellikle haksız avantaj elde eden yakın arkadaş","e1":"He appointed his old cronies to top jobs.","e1t":"Eski kafadarlarını üst düzey işlere atadı.","e2":"Cronyism.","e2t":"Eş dost kayırmacılığı."},{"w":"crux","tr":"en can alıcı nokta / temel mesele","te":"Noun","tt":"İsim","de":"The most important or difficult part of a problem","dt":"Bir sorunun en önemli veya en zor kısmı","e1":"The crux of the matter is...","e1t":"Meselenin can alıcı noktası şudur ki...","e2":"Now we come to the crux of the argument.","e2t":"Şimdi iddianın temel noktasına geliyoruz."},{"w":"cryptic","tr":"gizemli / anlaşılmaz / kapalı","te":"Adjective","tt":"Sıfat","de":"Mysterious or having a hidden meaning","dt":"Gizemli veya saklı bir anlamı olan","e1":"A cryptic message.","e1t":"Gizemli bir mesaj.","e2":"I got a cryptic text from him.","e2t":"Ondan ne anlama geldiği belirsiz bir mesaj aldım."},{"w":"cuisine","tr":"mutfak türü / yemek kültürü","te":"Noun","tt":"İsim","de":"A style of cooking","dt":"Bir yemek pişirme tarzı","e1":"Turkish cuisine.","e1t":"Türk mutfağı.","e2":"International cuisine.","e2t":"Uluslararası mutfak."},{"w":"culmination","tr":"doruk noktası / sonuç / zirve","te":"Noun","tt":"İsim","de":"The final act or result of a long period of work","dt":"Uzun bir çalışma döneminin son aşaması veya sonucu","e1":"The culmination of years of research.","e1t":"Yıllar süren araştırmanın doruk noktası (sonucu).","e2":"To reach its culmination.","e2t":"Zirvesine ulaşmak."},{"w":"culpable","tr":"suçlu / kusurlu / hatalı","te":"Adjective","tt":"Sıfat","de":"Deserving to be blamed or considered responsible","dt":"Suçlanmayı veya sorumlu tutulmayı hak eden","e1":"He was held culpable for the accident.","e1t":"Kazadan sorumlu (kusurlu) tutuldu.","e2":"Culpable homicide.","e2t":"Kusurlu (taksirli) adam öldürme."},{"w":"cumbersome","tr":"hantal / ağır / zahmetli","te":"Adjective","tt":"Sıfat","de":"Difficult to carry or manage because of size or weight","dt":"Boyut veya ağırlık nedeniyle taşıması veya yönetmesi zor","e1":"Cumbersome equipment.","e1t":"Hantal ekipman.","e2":"A cumbersome legal process.","e2t":"Zahmetli (yavaş ilerleyen) bir yasal süreç."},{"w":"cunning","tr":"kurnazlık / beceri / kurnaz","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Skill in achieving one's ends by deceit; or clever","dt":"İstediğini aldatmacayla elde etme becerisi; veya zeki","e1":"As cunning as a fox.","e1t":"Tilki kadar kurnaz.","e2":"A cunning plan.","e2t":"Kurnazca bir plan."},{"w":"curtail","tr":"azaltmak / kısıtlamak / kısa kesmek","te":"Verb","tt":"Fiil","de":"To stop or limit something","dt":"Bir şeyi durdurmak veya sınırlamak","e1":"We must curtail our spending.","e1t":"Harcamalarımızı kısıtlamalıyız.","e2":"To curtail a speech.","e2t":"Bir konuşmayı kısa kesmek."},{"w":"dabble","tr":"yüzeysel ilgilenmek / hobi olarak yapmak / (suyu) sıçratmak","te":"Verb","tt":"Fiil","de":"To take a slight and not serious interest in a subject","dt":"Bir konuyla ciddi olmayan, yüzeysel bir şekilde ilgilenmek","e1":"He dabbles in politics.","e1t":"Siyasetle (yüzeysel olarak) uğraşıyor.","e2":"To dabble in the stock market.","e2t":"Borsada şansını denemek (yüzeysel takılmak)."},{"w":"dawdle","tr":"oyalanmak / sallanmak / vaktini boşa harcamak","te":"Verb","tt":"Fiil","de":"To do something or go somewhere very slowly","dt":"Bir şeyi çok yavaş yapmak veya bir yere çok yavaş gitmek","e1":"Stop dawdling and get dressed!","e1t":"Oyalanmayı bırak da giyin!","e2":"To dawdle along the way.","e2t":"Yol boyunca oyalanmak."},{"w":"deadlock","tr":"çıkmaz / kilitlenme / düğüm","te":"Noun/Verb","tt":"İsim/Fiil","de":"A situation in which agreement cannot be reached","dt":"Anlaşmaya varılamayan durum","e1":"To reach a deadlock in negotiations.","e1t":"Müzakerelerde çıkmaza girmek.","e2":"To break the deadlock.","e2t":"Düğümü çözmek (çıkmazı aşmak)."},{"w":"debacle","tr":"fiyasko / tam bir başarısızlık","te":"Noun","tt":"İsim","de":"A complete failure, especially one that is embarrassing","dt":"Özellikle utanç verici olan tam bir başarısızlık","e1":"The election was a complete debacle for the party.","e1t":"Seçim, parti için tam bir fiyaskoydu.","e2":"Economic debacle.","e2t":"Ekonomik çöküş."},{"w":"debase","tr":"değerini düşürmek / aşağı çekmek / yozlaştırmak","te":"Verb","tt":"Fiil","de":"To reduce the quality or value of something","dt":"Bir şeyin kalitesini veya değerini düşürmek","e1":"To debase the currency.","e1t":"Paranın değerini düşürmek.","e2":"This movie debases women.","e2t":"Bu film kadınları aşağılıyor (küçültüyor)."},{"w":"debauchery","tr":"sefahat / ahlaksızlık / aşırı eğlence","te":"Noun","tt":"İsim","de":"Excessive indulgence in physical pleasures","dt":"Fiziksel zevklere aşırı düşkünlük","e1":"A life of debauchery.","e1t":"Sefahat dolu bir hayat.","e2":"Drunken debauchery.","e2t":"Sarhoşça ahlaksızlık (eğlence)."},{"w":"debilitate","tr":"zayıflatmak / güçsüzleştirmek","te":"Verb","tt":"Fiil","de":"To make someone or something physically weak","dt":"Birini veya bir şeyi fiziksel olarak zayıflatmak","e1":"The illness debilitated him.","e1t":"Hastalık onu güçsüz düşürdü.","e2":"A debilitating disease.","e2t":"Güçten düşüren (zayıflatan) hastalık."},{"w":"debris","tr":"enkaz / kalıntı / döküntü","te":"Noun","tt":"İsim","de":"Broken or torn pieces of something larger","dt":"Daha büyük bir şeyin kırılmış veya yırtılmış parçaları","e1":"Clear away the debris after the explosion.","e1t":"Patlamadan sonra enkazı temizleyin.","e2":"Space debris.","e2t":"Uzay çöpleri (kalıntıları)."},{"w":"debut","tr":"ilk sahneye çıkış / başlangıç / çıkış yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The first public appearance of an entertainer or sports player","dt":"Bir sanatçı veya sporcunun halk önüne ilk çıkışı","e1":"She made her professional debut at 16.","e1t":"Profesyonel çıkışını 16 yaşında yaptı.","e2":"Debut album.","e2t":"İlk (çıkış) albümü."},{"w":"decadent","tr":"çürümüş / yozlaşmış / aşırı lüks ve ahlaksız","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having low moral standards and interested in pleasure","dt":"Düşük ahlaki standartlara sahip ve zevk düşkünü","e1":"A decadent lifestyle.","e1t":"Yozlaşmış (sefahat dolu) yaşam tarzı.","e2":"Decadent chocolate cake (excessively rich).","e2t":"Çok yoğun ve lezzetli çikolatalı kek."},{"w":"decimate","tr":"büyük kısmını yok etmek / kırmak","te":"Verb","tt":"Fiil","de":"To kill or destroy a large part of something","dt":"Bir şeyin büyük bir bölümünü öldürmek veya yok etmek","e1":"The population was decimated by the plague.","e1t":"Nüfus veba tarafından kırıldı (yok edildi).","e2":"To decimate the forest.","e2t":"Ormanın büyük kısmını yok etmek."},{"w":"decipher","tr":"şifre çözmek / anlamını çözmek","te":"Verb","tt":"Fiil","de":"To discover the meaning of something written in code or badly","dt":"Kodla veya kötü yazılmış bir şeyin anlamını çözmek","e1":"I can't decipher his handwriting.","e1t":"Onun el yazısını çözemiyorum (okuyamıyorum).","e2":"To decipher a code.","e2t":"Bir şifreyi çözmek."},{"w":"decisive","tr":"karar verici / kesin / kararlı","te":"Adjective","tt":"Sıfat","de":"Strongly affecting how a situation will progress; or able to make choices","dt":"Bir durumun gidişatını güçlü bir şekilde etkileyen; veya kararlı","e1":"A decisive victory.","e1t":"Kesin bir zafer.","e2":"You need to be more decisive.","e2t":"Daha kararlı olmalısın."},{"w":"declaim","tr":"yüksek sesle söylemek / nutuk çekmek","te":"Verb","tt":"Fiil","de":"To speak loudly and with great feeling","dt":"Yüksek sesle ve büyük bir duyguyla konuşmak","e1":"He declaimed his poetry to the audience.","e1t":"Şiirlerini dinleyicilere karşı yüksek sesle okudu (nutuk gibi söyledi).","e2":"To declaim against injustice.","e2t":"Adaletsizliğe karşı nutuk çekmek."},{"w":"decompose","tr":"çürümek / ayrışmak","te":"Verb","tt":"Fiil","de":"To decay or break down into simpler parts","dt":"Çürümek veya daha basit parçalara ayrılmak","e1":"The body began to decompose.","e1t":"Vücut çürümeye başladı.","e2":"Bacteria decompose organic matter.","e2t":"Bakteriler organik maddeyi ayrıştırır."},{"w":"decorum","tr":"görgü / nezaket / adap","te":"Noun","tt":"İsim","de":"Behavior that is controlled, calm, and polite","dt":"Kontrollü, sakin ve nazik davranış","e1":"To behave with decorum.","e1t":"Adap (görgü) kurallarına göre davranmak.","e2":"A sense of decorum.","e2t":"Terbiye duygusu."},{"w":"decry","tr":"kötülemek / kınamak / eleştirmek","te":"Verb","tt":"Fiil","de":"To criticize something as being bad or without value","dt":"Bir şeyi kötü veya değersiz bularak eleştirmek","e1":"To decry the use of violence.","e1t":"Şiddet kullanımını kınamak.","e2":"Many doctors decry the new law.","e2t":"Birçok doktor yeni yasayı kötülüyor."},{"w":"deface","tr":"yüzünü bozmak / tahrif etmek / zarar vermek","te":"Verb","tt":"Fiil","de":"To damage and spoil the appearance of something","dt":"Bir şeyin görünüşüne zarar vermek ve bozmak","e1":"To deface a building with graffiti.","e1t":"Grafiti ile bir binanın görünüşünü bozmak.","e2":"To deface a monument.","e2t":"Bir anıta zarar vermek (tahrif etmek)."},{"w":"default","tr":"varsayılan / ödememek / yükümlülüğünü yerine getirmeme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A failure to do something, such as pay a debt","dt":"Bir borcu ödememe gibi yükümlülüğü yerine getirmeme durumu","e1":"By default (because no one else did it).","e1t":"Varsayılan olarak (başka kimse yapmadığı için).","e2":"To default on a loan.","e2t":"Bir krediyi ödeyememek (temerrüde düşmek)."},{"w":"defeasible","tr":"hükümsüz kılınabilir / çürütülebilir","te":"Adjective","tt":"Sıfat","de":"Able to be made invalid or void","dt":"Geçersiz veya hükümsüz kılınabilen","e1":"A defeasable contract.","e1t":"Hükümsüz kılınabilir bir sözleşme.","e2":"Defeasible reasoning (philosophy).","e2t":"Çürütülebilir akıl yürütme."},{"w":"defeatist","tr":"yenilgiyi kabullenmiş / yılgın","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Expecting to fail and so not even trying","dt":"Başarısız olmayı bekleyen ve bu yüzden denemeyen bile","e1":"A defeatist attitude.","e1t":"Yenilgiyi baştan kabul eden (yılgın) tutum.","e2":"Don't be such a defeatist!","e2t":"Bu kadar yılgın olma!"},{"w":"defector","tr":"dönek / saf değiştiren kişi","te":"Noun","tt":"İsim","de":"A person who leaves their country or group to join an enemy","dt":"Düşmana katılmak için ülkesini veya grubunu terk eden kişi","e1":"A political defector.","e1t":"Siyasi dönek (saf değiştiren).","e2":"A defector from North Korea.","e2t":"Kuzey Kore'den kaçan biri."},{"w":"defiance","tr":"karşı gelme / başkaldırı / meydan okuma","te":"Noun","tt":"İsim","de":"Behavior that shows you refuse to obey someone","dt":"Birine itaat etmeyi reddettiğinizi gösteren davranış","e1":"In defiance of the law.","e1t":"Yasaya karşı gelerek (meydan okuyarak).","e2":"An act of defiance.","e2t":"Bir başkaldırı eylemi."},{"w":"deft","tr":"ustaca / maharetli / çevik","te":"Adjective","tt":"Sıfat","de":"Skillful, clever, and quick in movement","dt":"Hareketlerinde yetenekli, zeki ve hızlı","e1":"With a deft movement of her hand.","e1t":"Elinin maharetli bir hareketiyle.","e2":"A deft touch.","e2t":"Ustaca bir dokunuş."},{"w":"defunct","tr":"artık mevcut olmayan / ölü / feshedilmiş","te":"Adjective","tt":"Sıfat","de":"No longer existing, living, or working","dt":"Artık var olmayan, yaşamayan veya çalışmayan","e1":"A defunct organization.","e1t":"Artık faaliyette olmayan (feshedilmiş) kuruluş.","e2":"A defunct law.","e2t":"Yürürlükten kalkmış (ölü) yasa."},{"w":"degenerate","tr":"yozlaşmak / bozulmak / kötüye gitmek","te":"Verb/Adj/Noun","tt":"To become worse in quality; or having low moral standards","de":"Kalite olarak kötüleşmek; veya düşük ahlaki standartlara sahip olmak","dt":"The protest degenerated into violence.","e1":"Protesto şiddete dönüştü (yozlaştı).","e1t":"Degenerate art.","e2":"Yozlaşmış sanat.","e2t":""},{"w":"degradation","tr":"kötüleşme / aşağılanma / bozulma","te":"Noun","tt":"İsim","de":"The process of something becoming worse or being damaged","dt":"Bir şeyin kötüleşmesi, zarar görmesi veya aşağılanması süreci","e1":"Environmental degradation.","e1t":"Çevresel bozulma.","e2":"The degradation of being poor.","e2t":"Fakir olmanın getirdiği aşağılanma (onur kırıklığı)."},{"w":"dehydrate","tr":"susuz bırakmak / su kaybetmek","te":"Verb","tt":"Fiil","de":"To lose water, or to cause water to be lost from something","dt":"Su kaybetmek veya bir şeyin su kaybetmesine neden olmak","e1":"Runners can easily dehydrate in hot weather.","e1t":"Koşucular sıcak havada kolayca su kaybedebilir.","e2":"Dehydrated fruit.","e2t":"Kurutulmuş (suyu alınmış) meyve."},{"w":"dejected","tr":"umutsuz / morali bozuk / kederli","te":"Adjective","tt":"Sıfat","de":"Unhappy and disappointed","dt":"Mutsuz ve hayal kırıklığına uğramış","e1":"He looked dejected after losing the match.","e1t":"Maçı kaybettikten sonra umutsuz (yıkılmış) görünüyordu.","e2":"A dejected expression.","e2t":"Kederli bir ifade."},{"w":"delicacy","tr":"incelik / hassasiyet / nadide yiyecek","te":"Noun","tt":"İsim","de":"The quality of being easy to damage; or a rare and expensive food","dt":"Kolayca zarar görebilme niteliği; veya nadir ve pahalı yiyecek","e1":"The delicacy of the negotiations.","e1t":"Müzakerelerin hassasiyeti (inceliği).","e2":"Caviar is a great delicacy.","e2t":"Havyar çok nadide bir yiyecektir."},{"w":"delineate","tr":"tasvir etmek / sınırlarını çizmek / betimlemek","te":"Verb","tt":"Fiil","de":"To describe or mark the edge of something accurately","dt":"Bir şeyi doğru bir şekilde tanımlamak veya sınırlarını belirlemek","e1":"To delineate the responsibilities of each department.","e1t":"Her departmanın sorumluluklarını belirlemek (çizgisini çekmek).","e2":"The boundary is clearly delineated on the map.","e2t":"Sınır, haritada net bir şekilde tasvir edilmiş (belirlenmiş)."},{"w":"delirious","tr":"kendinden geçmiş / sayıklayan / çılgınca mutlu","te":"Adjective","tt":"Sıfat","de":"Unable to think clearly due to fever; or extremely happy","dt":"Ateşten dolayı sayıklayan; veya son derece mutlu","e1":"The patient was delirious with fever.","e1t":"Hasta ateşten dolayı sayıklıyordu.","e2":"The fans were delirious with joy.","e2t":"Taraftarlar sevinçten kendinden geçmişti."},{"w":"deluge","tr":"sel / tufan / sağanak / yağmuruna tutmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very large amount of rain or water; or a large number of things","dt":"Çok büyük miktarda yağmur/su; veya çok sayıda şey","e1":"A deluge of complaints.","e1t":"Şikayet yağmuru (tufanı).","e2":"The office was deluged with calls.","e2t":"Ofis telefon yağmuruna tutuldu."},{"w":"demarcation","tr":"sınır çizme / ayrım / sınır hattı","te":"Noun","tt":"İsim","de":"A border or a line that separates two things","dt":"İki şeyi birbirinden ayıran sınır veya hat","e1":"A clear demarcation between the two roles.","e1t":"İki rol arasında net bir ayrım (sınır).","e2":"Demarcation line.","e2t":"Sınır hattı."},{"w":"demean","tr":"küçültmek / alçaltmak / değerini düşürmek","te":"Verb","tt":"Fiil","de":"To cause someone to become less respected","dt":"Birinin daha az saygı görmesine neden olmak","e1":"I wouldn't demean myself by asking for money.","e1t":"Para isteyerek kendimi alçaltmazdım.","e2":"Such behavior demeans the office of the presidency.","e2t":"Bu tarz davranışlar başkanlık makamını küçültür."},{"w":"demeanor / demeanour","tr":"tutum / davranış / tavır","te":"Noun","tt":"İsim","de":"A person's outward behavior or appearance","dt":"Bir kişinin dışarıya yansıyan davranışı veya görünüşü","e1":"A professional demeanor.","e1t":"Profesyonel bir tavır.","e2":"He maintained a calm demeanor throughout the trial.","e2t":"Duruşma boyunca sakin bir tutum sergiledi."},{"w":"demented","tr":"çıldırmış / aklını kaçırmış / çılgın","te":"Adjective","tt":"Sıfat","de":"Unable to think clearly; or crazy","dt":"Net düşünemeyen; veya çılgın","e1":"He was demented with worry.","e1t":"Endişeden çıldırmış haldeydi.","e2":"A demented scream.","e2t":"Çılgınca (korkunç) bir çığlık."},{"w":"demise","tr":"ölüm / sona erme / batış","te":"Noun","tt":"İsim","de":"The end of something that was previously great; or death","dt":"Önceden büyük olan bir şeyin sonu; veya ölüm","e1":"The demise of the Ottoman Empire.","e1t":"Osmanlı İmparatorluğu'nun çöküşü (sonu).","e2":"His untimely demise.","e2t":"Onun zamansız ölümü."},{"w":"demoralize / demoralise","tr":"moral bozmak / cesaretini kırmak","te":"Verb","tt":"Fiil","de":"To make someone lose much of their confidence","dt":"Birinin özgüvenini yitirmesine neden olmak","e1":"The defeat demoralized the whole team.","e1t":"Yenilgi tüm takımın moralini bozdu.","e2":"Demoralizing news.","e2t":"Cesaret kırıcı (moral bozucu) haberler."},{"w":"demote","tr":"rütbe düşürmek / tenzil","te":"i rütbe yapmak","tt":"Verb","de":"Fiil","dt":"To lower someone's rank or position","e1":"Birinin rütbesini veya konumunu düşürmek","e1t":"He was demoted to a junior position.","e2":"Alt bir pozisyona düşürüldü.","e2t":"To demote a student to a lower class."},{"w":"demur","tr":"itiraz etmek / karşı çıkmak / duraksamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To express disagreement or refuse to do something","dt":"Anlaşmazlık belirtmek veya bir şeyi yapmayı reddetmek","e1":"Most people accepted the decision without demur.","e1t":"Çoğu insan kararı itiraz etmeden kabul etti.","e2":"She demurred when asked to work late.","e2t":"Geç saatlere kadar çalışması istendiğinde itiraz etti."},{"w":"denigrate","tr":"kötülemek / karalamak / aşağılamak","te":"Verb","tt":"Fiil","de":"To say that someone or something is not good or important","dt":"Birinin veya bir şeyin iyi veya önemli olmadığını söylemek","e1":"You shouldn't denigrate his achievements.","e1t":"Onun başarılarını küçümsememelisin (karalamamalısın).","e2":"To denigrate a person's character.","e2t":"Birinin karakterini kötülemek."},{"w":"denounce","tr":"suçlamak / ihbar etmek / kınamak (herkesin önünde)","te":"Verb","tt":"Fiil","de":"To publicly state that someone or something is bad","dt":"Birinin veya bir şeyin kötü olduğunu herkesin önünde söylemek","e1":"The government was denounced for its failure to act.","e1t":"Hükümet harekete geçmediği için kınandı.","e2":"To denounce a traitor to the police.","e2t":"Bir haini polise ihbar etmek."},{"w":"deplete","tr":"tüketmek / boşaltmak / azaltmak","te":"Verb","tt":"Fiil","de":"To reduce something in size or amount","dt":"Bir şeyi boyut veya miktar olarak azaltmak","e1":"War had depleted the country's resources.","e1t":"Savaş ülkenin kaynaklarını tüketmişti.","e2":"Depleted uranium.","e2t":"Seyreltilmiş (tüketilmiş) uranyum."},{"w":"deplorable","tr":"acınacak halde / berbat / kınanacak","te":"Adjective","tt":"Sıfat","de":"Very bad and causing shock, fear, or combined disgust","dt":"Şok, korku veya tiksinti yaratan, çok kötü","e1":"Deplorable living conditions.","e1t":"Acınacak haldeki (berbat) yaşam koşulları.","e2":"Your conduct is deplorable.","e2t":"Davranışınız kınanacak türden."},{"w":"depose","tr":"görevden almak / ifade vermek (hukuk)","te":"Verb","tt":"Fiil","de":"To remove someone important from a powerful position","dt":"Önemli birini güçlü bir konumdan almak","e1":"The king was deposed in a military coup.","e1t":"Kral bir askeri darbeyle tahttan indirildi (görevden alındı).","e2":"The witness was deposed (to give evidence under oath).","e2t":"Tanığın (yeminli) ifadesi alındı."},{"w":"deprecate","tr":"onaylamamak / küçümsemek / değerini düşürmek","te":"Verb","tt":"Fiil","de":"To not approve of something; or to say it is not important","dt":"Bir şeyi onaylamamak; veya önemli olmadığını söylemek","e1":"Self","e1t":"deprecating humor.","e2":"Kendini küçümseyen (kendinle dalga geçen) mizah.","e2t":"He deprecated the use of force."},{"w":"deranged","tr":"akli dengesi bozuk / çıldırmış","te":"Adjective","tt":"Sıfat","de":"Mentally ill and behaving in a very strange way","dt":"Zihinsel olarak hasta ve garip davranan","e1":"A deranged gunman.","e1t":"Akli dengesi yerinde olmayan silahlı saldırgan.","e2":"He was deranged with grief.","e2t":"Kederden aklını yitirmişti."},{"w":"derelict","tr":"terk edilmiş / sahipsiz / harap","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a building/place) empty and in bad condition","dt":"(Bina/yer için) boş ve kötü durumda","e1":"A derelict warehouse.","e1t":"Terk edilmiş (harap) bir depo.","e2":"Derelict land.","e2t":"Atıl (sahipsiz) arazi."},{"w":"deride","tr":"alay etmek / küçümsemek","te":"Verb","tt":"Fiil","de":"To laugh at someone or something in a cruel way","dt":"Birine veya bir şeye zalimce gülmek","e1":"His views were derided by the critics.","e1t":"Görüşleri eleştirmenler tarafından alaya alındı.","e2":"To deride someone's efforts.","e2t":"Birinin çabalarını küçümsemek."},{"w":"derivative","tr":"türev / türetilmiş / özgün olmayan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something that has developed from something else; or not original","dt":"Başka bir şeyden gelişmiş olan; veya orijinal olmayan","e1":"Financial derivatives.","e1t":"Finansal türevler.","e2":"His painting style is rather derivative.","e2t":"Resim tarzı oldukça (başkasından) alıntılama (özgün değil)."},{"w":"derogatory","tr":"aşağılayıcı / küçümseyici","te":"Adjective","tt":"Sıfat","de":"Showing strong disapproval and not showing respect","dt":"Güçlü bir onaylamama ve saygısızlık gösteren","e1":"Derogatory remarks about his weight.","e1t":"Kilosu hakkında aşağılayıcı yorumlar.","e2":"To use a derogatory term.","e2t":"Aşağılayıcı bir terim kullanmak."},{"w":"descendent / descendant","tr":"torun / oğul / soyundan gelen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is related to someone from the past","dt":"Geçmişteki birinin soyundan gelen kişi","e1":"He is a direct descendant of Napoleon.","e1t":"Napoleon'un doğrudan soyundan gelmektedir.","e2":"Descendant species.","e2t":"Sonraki (türeyen) türler."},{"w":"desecrate","tr":"kutsal şeye saygısızlık etmek / kirletmek","te":"Verb","tt":"Fiil","de":"To damage or show no respect toward a holy place","dt":"Kutsal bir yere zarar vermek veya saygısızlık göstermek","e1":"To desecrate a grave.","e1t":"Bir mezara saygısızlık etmek (kirletmek).","e2":"Desecration of the temple.","e2t":"Tapınağın kirletilmesi."},{"w":"desiccate","tr":"kurutmak / suyunu çekmek","te":"Verb","tt":"Fiil","de":"To remove the moisture from something to preserve it","dt":"Korumak amacıyla bir şeyin nemini almak","e1":"Desiccated coconut.","e1t":"Hindistan cevizi rendesi (kurutulmuş).","e2":"The sun desiccated the soil.","e2t":"Güneş toprağı kuruttu (çoraklaştırdı)."},{"w":"desirous","tr":"arzu duyan / istekli","te":"Adjective","tt":"Sıfat","de":"Wanting something very much","dt":"Bir şeyi çok isteyen","e1":"Desirous of success.","e1t":"Başarıya aç (başarıyı arzulayan).","e2":"I am desirous to know the truth.","e2t":"Gerçeği bilmek istiyorum."},{"w":"desist","tr":"vazgeçmek / durmak / bırakmak","te":"Verb","tt":"Fiil","de":"To stop doing something","dt":"Bir şeyi yapmayı bırakmak","e1":"The court ordered them to cease and desist.","e1t":"Mahkeme onlara durmalarını ve (faaliyeti) bırakmalarını emretti.","e2":"Please desist from making noise.","e2t":"Lütfen gürültü yapmaktan vazgeçin."},{"w":"desolate","tr":"ıssız / terkedilmiş / perişan","te":"Adjective/Verb","tt":"(Of a place) empty and without people; or very lonely","de":"(Yer için) ıssız ve insansız; veya çok yalnız (mutsuz)","dt":"A desolate landscape.","e1":"Issız (kasvetli) bir manzara.","e1t":"She felt desolate after he left.","e2":"O gittikten sonra kendini perişan (yalnız) hissetti.","e2t":""},{"w":"despise","tr":"hor görmek / küçümsemek / nefret etmek","te":"Verb","tt":"Fiil","de":"To feel a strong dislike for someone or something","dt":"Birine veya bir şeye karşı güçlü bir nefret/küçümseme hissetmek","e1":"I despise people who tell lies.","e1t":"Yalan söyleyen insanları hor görürüm (nefret ederim).","e2":"He is despised by his colleagues.","e2t":"Meslektaşları tarafından küçümseniyor."},{"w":"despondent","tr":"umutsuz / karamsar / kederli","te":"Adjective","tt":"Sıfat","de":"Unhappy and with no hope","dt":"Mutsuz ve umutsuz","e1":"He became increasingly despondent about his chances.","e1t":"Şansı konusunda giderek daha fazla umutsuzluğa kapıldı.","e2":"A despondent mood.","e2t":"Karamsar bir ruh hali."},{"w":"despot","tr":"zorba yönetici / despot / diktatör","te":"Noun","tt":"İsim","de":"A ruler who has unlimited power and uses it cruelly","dt":"Sınırsız gücü olan ve bunu zalimce kullanan yönetici","e1":"An enlightened despot.","e1t":"Aydın despot (mutlakiyetçi yönetici).","e2":"To live under a despot.","e2t":"Bir zorbanın yönetimi altında yaşamak."},{"w":"destitute","tr":"yoksul / muhtaç / yoksun","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Without money, food, a home, or possessions","dt":"Parası, yiyeceği, evi veya malı olmayan","e1":"The flood left many families destitute.","e1t":"Sel birçok aileyi muhtaç (yoksul) bıraktı.","e2":"Destitute of ideas (lacking).","e2t":"Fikirden yoksun."},{"w":"desultory","tr":"dağınık / düzensiz / üstünkörü","te":"Adjective","tt":"Sıfat","de":"Without a clear plan or purpose and showing little effort","dt":"Net bir planı veya amacı olmayan ve az çaba gösteren","e1":"A desultory conversation.","e1t":"Havadan sudan (dağınık) bir konuşma.","e2":"To work in a desultory fashion.","e2t":"Gelişigüzel (düzensiz) bir şekilde çalışmak."},{"w":"detain","tr":"alıkoymak / gözaltına almak / geciktirmek","te":"Verb","tt":"Fiil","de":"To force someone to stay in a place; or to delay someone","dt":"Birini bir yerde kalmaya zorlamak; veya geciktirmek","e1":"The police detained the suspect for questioning.","e1t":"Polis şüpheliyi sorgu için gözaltına aldı.","e2":"I'm sorry I'm late, I was detained at the office.","e2t":"Geciktiğim için üzgünüm, ofiste alıkonuldum (işim çıktı)."},{"w":"detectable","tr":"tespit edilebilir / fark edilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be noticed or discovered","dt":"Fark edilebilen veya keşfedilebilen","e1":"A detectable change in temperature.","e1t":"Sıcaklıkta fark edilebilir bir değişim.","e2":"Hard to find, but still detectable.","e2t":"Bulması zor ama yine de tespit edilebilir."},{"w":"detest","tr":"nefret etmek / tiksinmek","te":"Verb","tt":"Fiil","de":"To hate someone or something very much","dt":"Birinden veya bir şeyden çok nefret etmek","e1":"I detest cruelty to animals.","e1t":"Hayvanlara yapılan eziyetten nefret ederim.","e2":"They detest each other.","e2t":"Birbirlerinden nefret ediyorlar."},{"w":"detrimental","tr":"zararlı / nahoş","te":"Adjective","tt":"Sıfat","de":"Causing harm or damage","dt":"Zarar veya hasara neden olan","e1":"Smoking is detrimental to your health.","e1t":"Sigara içmek sağlığınıza zararlıdır.","e2":"The policy had a detrimental effect on the economy.","e2t":"Politikanın ekonomi üzerinde nahoş (kötü) bir etkisi oldu."},{"w":"devious","tr":"dolambaçlı / sinsi / kurnaz","te":"Adjective","tt":"Sıfat","de":"Dishonest or tricky; or not direct","dt":"Dürüst olmayan veya hileli; veya doğrudan olmayan","e1":"A devious plan to get money.","e1t":"Para elde etmek için sinsi bir plan.","e2":"A devious route.","e2t":"Dolambaçlı bir yol."},{"w":"devoid","tr":"yoksun / mahrum","te":"Adjective","tt":"Sıfat","de":"Completely lacking in something","dt":"Bir şeyden tamamen yoksun","e1":"A landscape devoid of life.","e1t":"Yaşamdan yoksun bir manzara.","e2":"His voice was devoid of emotion.","e2t":"Sesi duygudan mahrumdu."},{"w":"devout","tr":"dindar / koyu / samimi","te":"Adjective","tt":"Sıfat","de":"Having very strong religious beliefs; or sincere","dt":"Çok güçlü dini inançları olan; veya samimi","e1":"A devout Muslim.","e1t":"Dindar bir Müslüman.","e2":"A devout supporter of the cause.","e2t":"Davanın sadık (koyu) bir destekçisi."},{"w":"dexterity","tr":"el becerisi / marifet / kıvraklık","te":"Noun","tt":"İsim","de":"Skill in using your hands or your mind","dt":"Elleri veya zihni kullanma becerisi","e1":"He played the piece with great manual dexterity.","e1t":"Parçayı büyük bir el becerisiyle çaldı.","e2":"Mental dexterity.","e2t":"Zihinsel kıvraklık."},{"w":"dialect","tr":"lehçe / ağız","te":"Noun","tt":"İsim","de":"A form of a language that is spoken in a particular area","dt":"Belirli bir bölgede konuşulan dil biçimi","e1":"He speaks a local dialect of German.","e1t":"Almancanın yerel bir lehçesini konuşuyor.","e2":"Regional dialects.","e2t":"Bölgesel ağızlar."},{"w":"diametrical","tr":"tamamen zıt / çapla ilgili","te":"Adjective","tt":"Sıfat","de":"Completely opposite","dt":"Tamamen zıt","e1":"They hold diametrical views on the issue.","e1t":"Bu konuda taban tabana zıt görüşlere sahipler.","e2":"Diametrical opposition.","e2t":"Tam karşıtlık."},{"w":"dichotomy","tr":"ikilik / ikiye bölünme / çelişki","te":"Noun","tt":"İsim","de":"A difference between two completely opposite ideas or groups","dt":"İki tamamen zıt fikir veya grup arasındaki fark","e1":"The dichotomy between theory and practice.","e1t":"Teori ve pratik arasındaki ikilik (çelişki).","e2":"A rigid dichotomy.","e2t":"Keskin bir ayrım."},{"w":"dictate","tr":"dikte etmek / emretmek / yazdırmak","te":"Verb","tt":"Fiil","de":"To give orders, or to say words for someone else to write down","dt":"Emir vermek veya birinin yazması için kelimeleri söylemek","e1":"To dictate a letter to a secretary.","e1t":"Sekretere mektup yazdırmak.","e2":"The rules dictate how we behave.","e2t":"Kurallar nasıl davranacağımızı belirler (dikte eder)."},{"w":"didactic","tr":"öğretici / didaktik / bilgiçlik taslayan","te":"Adjective","tt":"Sıfat","de":"Intended to teach, especially in a way that is too serious","dt":"Özellikle çok ciddi bir şekilde öğretmeyi amaçlayan","e1":"A didactic approach to education.","e1t":"Eğitime öğretici (didaktik) bir yaklaşım.","e2":"His novel is rather didactic.","e2t":"Romanı oldukça öğreticidir (öğüt vericidir)."},{"w":"digress","tr":"konudan sapmak / sözü dağıtmak","te":"Verb","tt":"Fiil","de":"To move away from the main subject you are talking about","dt":"Konuşulan ana konudan uzaklaşmak","e1":"To digress from the main point.","e1t":"Ana noktadan sapmak.","e2":"Let me digress for a moment.","e2t":"Bir an için konuyu dağıtmama izin verin."},{"w":"dilapidated","tr":"harap / yıkık dökük / bakımsız","te":"Adjective","tt":"Sıfat","de":"Old and in very bad condition","dt":"Eski ve çok kötü durumda","e1":"A dilapidated old building.","e1t":"Harap, eski bir bina.","e2":"The car was in a dilapidated state.","e2t":"Araba dökülüyordu (harap haldeydi)."},{"w":"din","tr":"gürültü / velvele / patırtı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A loud, unpleasant confused noise that lasts a long time","dt":"Uzun süren, nahoş ve yüksek sesli gürültü","e1":"I couldn't hear him over the din of the machines.","e1t":"Makinelerin gürültüsü arasında onu duyamadım.","e2":"To make a din.","e2t":"Patırtı çıkarmak."},{"w":"dire","tr":"korkunç / vahim / dehşet verici","te":"Adjective","tt":"Sıfat","de":"Very serious or bad","dt":"Çok ciddi veya kötü","e1":"The company is in dire financial straits.","e1t":"Şirket korkunç bir finansal dar boğazda.","e2":"Dire consequences.","e2t":"Vahim sonuçlar."},{"w":"direful","tr":"uğursuz / korkunç / meşum","te":"Adjective","tt":"Sıfat","de":"Causing fear or dread (literary)","dt":"Korku veya dehşet uyandıran (edebi)","e1":"Direful news.","e1t":"Korkunç (meşum) haberler.","e2":"A direful warning.","e2t":"Dehşet verici bir uyarı."},{"w":"disavow","tr":"reddetmek / tanımadığını bildirmek / yalanlamak","te":"Verb","tt":"Fiil","de":"To say that you know nothing about something or are not responsible","dt":"Bir şey hakkında hiçbir şey bilmediğini veya sorumlu olmadığını söylemek","e1":"He disavowed the actions of his subordinates.","e1t":"Astlarının eylemlerini tanımadığını bildirdi (reddedetti).","e2":"To disavow a rumor.","e2t":"Bir söylentiyi yalanlamak."},{"w":"disband","tr":"dağıtmak / dağılmak (grup/ordu)","te":"Verb","tt":"Fiil","de":"To stop being a group","dt":"Bir grup olmayı bırakmak (dağılmak)","e1":"The army was disbanded after the war.","e1t":"Savaştan sonra ordu dağıtıldı.","e2":"To disband a committee.","e2t":"Bir komiteyi feshetmek (dağıtmak)."},{"w":"disburse","tr":"ödeme yapmak / para ödemek","te":"Verb","tt":"Fiil","de":"To pay out money, especially from a large amount that has been collected","dt":"Özellikle toplanan büyük bir miktardan para ödemek","e1":"The funds will be disbursed next week.","e1t":"Fonlar önümüzdeki hafta ödenecek (dağıtılacak).","e2":"To disburse a loan.","e2t":"Bir krediyi ödemek (serbest bırakmak)."},{"w":"discursive","tr":"dağınık / konudan konuya atlayan / rasyonel","te":"Adjective","tt":"Sıfat","de":"Moving from one subject to another without strict structure","dt":"Sıkı bir yapı olmadan konudan konuya atlayan","e1":"A long and discursive speech.","e1t":"Uzun ve dağınık bir konuşma.","e2":"Discursive reasoning (logical).","e2t":"Akılcı (mantıksal) akıl yürütme."},{"w":"disdain","tr":"küçümsemek / hor görmek / tenezzül etmemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The feeling of not liking someone because you think they are not important","dt":"Birini önemli görmediğiniz için hissettiğiniz hor görme duygusu","e1":"He showed total disdain for his critics.","e1t":"Eleştirmenlerini tamamen küçümsedi.","e2":"To disdain an offer.","e2t":"Bir teklifi hor görmek (reddetmek)."},{"w":"disengage","tr":"bağlantıyı kesmek / ayırmak / geri çekilmek","te":"Verb","tt":"Fiil","de":"To become separate or free from something","dt":"Bir şeyden ayrılmak veya bağımsız hale gelmek","e1":"To disengage the clutch (car).","e1t":"Debriyajdan ayağını çekmek (bağlantıyı kesmek).","e2":"To disengage from a conflict.","e2t":"Bir çatışmadan geri çekilmek."},{"w":"disfigure","tr":"biçimini bozmak / çirkinleştirmek","te":"Verb","tt":"Fiil","de":"To spoil the appearance of something","dt":"Bir şeyin görünüşünü bozmak","e1":"Her face was disfigured by a scar.","e1t":"Yüzü bir yara iziyle bozulmuştu.","e2":"To disfigure a landscape.","e2t":"Bir manzarayı çirkinleştirmek."},{"w":"dishearten","tr":"cesaretini kırmak / yıldırmak / umutsuzluğa düşürmek","te":"Verb","tt":"Fiil","de":"To cause someone to lose confidence or hope","dt":"Birinin özgüvenini veya umudunu yitirmesine neden olmak","e1":"Don't let this failure dishearten you.","e1t":"Bu başarısızlığın cesaretini kırmasına izin verme.","e2":"Disheartened by the news.","e2t":"Haberlerden dolayı umudu kırılmış."},{"w":"disheveled / dishevelled","tr":"darmadağınık / üstü başı dağınık","te":"Adjective","tt":"Sıfat","de":"(Of a person's appearance) very untidy","dt":"(Kişinin görünüşü için) çok dağınık","e1":"He looked disheveled after the long flight.","e1t":"Uzun uçuştan sonra darmadağınık görünüyordu.","e2":"Disheveled hair.","e2t":"Darmadağınık saçlar."},{"w":"disillusion","tr":"hayal kırıklığına uğratmak / gözünü açmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To disappoint someone by showing them the truth","dt":"Gerçeği göstererek birini hayal kırıklığına uğratmak","e1":"I hate to disillusion you, but the job is not easy.","e1t":"Hayal kırıklığına uğratmak istemem ama iş kolay değil.","e2":"Growing disillusionment with politics.","e2t":"Siyasete karşı artan hayal kırıklığı."},{"w":"disinclined","tr":"isteksiz / gönülsüz","te":"Adjective","tt":"Sıfat","de":"Not wanting to do something","dt":"Bir şeyi yapmayı istemeyen","e1":"I'm disinclined to help him after what he said.","e1t":"Söylediklerinden sonra ona yardım etmeye isteksizim.","e2":"Disinclined to work.","e2t":"Çalışmaya gönülsüz."},{"w":"disinfect","tr":"dezenfekte etmek / mikroplardan arındırmak","te":"Verb","tt":"Fiil","de":"To clean something using a chemical that kills bacteria","dt":"Bakterileri öldüren bir kimyasal kullanarak temizlemek","e1":"To disinfect a wound.","e1t":"Bir yarayı dezenfekte etmek.","e2":"Disinfectant spray.","e2t":"Dezenfektan sprey."},{"w":"disingenuous","tr":"samimiyetsiz / art niyetli / sinsi","te":"Adjective","tt":"Sıfat","de":"Slightly dishonest; not speaking everything you know","dt":"Biraz dürüst olmayan; bildiği her şeyi söylemeyen (sinsi)","e1":"It was disingenuous of him to say he didn't know.","e1t":"Bilmediğini söylemesi samimiyetsizceydi.","e2":"A disingenuous argument.","e2t":"Art niyetli bir iddia."},{"w":"dislodge","tr":"yerinden çıkarmak / sökmek / kovmak","te":"Verb","tt":"Fiil","de":"To remove something from its fixed position","dt":"Bir şeyi sabitlendiği yerden çıkarmak","e1":"The heavy rain dislodged several rocks.","e1t":"Şiddetli yağmur birkaç kayayı yerinden çıkardı.","e2":"To dislodge an enemy from their position.","e2t":"Bir düşmanı mevzisinden söküp atmak."},{"w":"dismissive","tr":"küçümseyici / önemsemeyen / reddeden","te":"Adjective","tt":"Sıfat","de":"Showing that you do not think something is important","dt":"Bir şeyin önemli olmadığını düşündüğünüzü gösteren","e1":"He was dismissive of my ideas.","e1t":"Fikirlerimi küçümsedi (önemsemedi).","e2":"A dismissive gesture.","e2t":"Önemsemeyen bir el hareketi."},{"w":"disobedient","tr":"itaatsiz / söz dinlemez","te":"Adjective","tt":"Sıfat","de":"Refusing to do what you are told to do","dt":"Kendisine söyleneni yapmayı reddeden","e1":"A disobedient child.","e1t":"Söz dinlemez bir çocuk.","e2":"Punishment for being disobedient.","e2t":"İtaatsizliğin cezası."},{"w":"disorderly","tr":"düzensiz / karışık / asayişi bozan","te":"Adjective","tt":"Sıfat","de":"Untidy or violent and causing trouble in public","dt":"Dağınık veya toplum içinde sorun çıkaran","e1":"A disorderly crowd.","e1t":"Taşkınlık yapan (asayişi bozan) bir kalabalık.","e2":"Disorderly conduct.","e2t":"Kamu düzenini bozan davranış."},{"w":"disorient / disorientate","tr":"yönünü şaşırtmak / kafasını karıştırmak","te":"Verb","tt":"Fiil","de":"To make someone feel confused about where they are","dt":"Birinin nerede olduğu konusunda kafasını karıştırmak","e1":"The bright lights disoriented me.","e1t":"Parlak ışıklar yönümü şaşırttı.","e2":"A disorienting experience.","e2t":"Kafa karıştırıcı (yön duygusunu bozan) bir deneyim."},{"w":"disparage","tr":"kötülemek / aşağılamak / küçük görmek","te":"Verb","tt":"Fiil","de":"To criticize someone in a way that shows no respect","dt":"Birini saygısızca eleştirmek","e1":"To disparage someone's efforts.","e1t":"Birinin çabalarını küçümsemek (kötülemek).","e2":"Disparaging remarks.","e2t":"Aşağılayıcı yorumlar."},{"w":"dispassionate","tr":"sakin / tarafsız / duygusuz","te":"Adjective","tt":"Sıfat","de":"Able to think clearly without being affected by emotions","dt":"Duygulardan etkilenmeden net düşünebilen","e1":"A dispassionate analysis of the facts.","e1t":"Gerçeklerin tarafsız (sakin) bir analizi.","e2":"He remained dispassionate during the argument.","e2t":"Tartışma sırasında sakinliğini korudu."},{"w":"dispel","tr":"dağıtmak / gidermek (şüphe/korku vb.)","te":"Verb","tt":"Fiil","de":"To make a feeling or belief disappear","dt":"Bir duyguyu veya inancı ortadan kaldırmak","e1":"The report dispelled any doubts about his honesty.","e1t":"Rapor, onun dürüstlüğü hakkındaki tüm şüpheleri giderdi.","e2":"To dispel a rumor.","e2t":"Bir söylentiyi dağıtmak."},{"w":"dispirited","tr":"morali bozuk / yılgın / hevesi kırılmış","te":"Adjective","tt":"Sıfat","de":"Lacking in spirit or enthusiasm","dt":"Şevki veya hevesi kalmamış","e1":"The team looked dispirited after their third loss.","e1t":"Üçüncü mağlubiyetten sonra takım yılgın görünüyordu.","e2":"Dispirited by failure.","e2t":"Başarısızlıktan dolayı morali bozuk."},{"w":"displace","tr":"yerinden etmek / göçe zorlamak / yerini almak","te":"Verb","tt":"Fiil","de":"To force something out of its usual place; or to take over","dt":"Bir şeyi yerinden çıkarmak veya birinin yerini almak","e1":"Thousands of people were displaced by the war.","e1t":"Savaş nedeniyle binlerce insan yerinden edildi (göçe zorlandı).","e2":"Coal has been displaced by natural gas.","e2t":"Kömürün yerini doğal gaz aldı."},{"w":"displease","tr":"kızdırmak / memnun etmemek / nahoş gelmek","te":"Verb","tt":"Fiil","de":"To make someone annoyed or unhappy","dt":"Birini kızdırmak veya mutsuz etmek","e1":"It displeased him to see such waste.","e1t":"Bu kadar israfı görmek onu memnun etmedi (kızdırdı).","e2":"To displease a superior.","e2t":"Bir üstünü (amirini) kızdırmak."},{"w":"disposable","tr":"tek kullanımlık / elden çıkarılabilir","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Intended to be thrown away after use","dt":"Kullanıldıktan sonra atılması amaçlanan","e1":"Disposable diapers.","e1t":"Tek kullanımlık bebek bezleri.","e2":"Disposable income (after tax).","e2t":"Harcanabilir (vergiden sonra kalan) gelir."},{"w":"disprove","tr":"çürütmek / aksini ispatlamak","te":"Verb","tt":"Fiil","de":"To prove that something is not true","dt":"Bir şeyin doğru olmadığını kanıtlamak","e1":"To disprove a theory.","e1t":"Bir teoriyi çürütmek.","e2":"The evidence disproves his claim.","e2t":"Kanıtlar onun iddiasını yalanlıyor (çürütüyor)."},{"w":"disregard","tr":"önemsememek / hiçe saymak / aldırmamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To ignore something or treat it as not important","dt":"Bir şeyi görmezden gelmek veya önemli değilmiş gibi davranmak","e1":"He showed total disregard for my feelings.","e1t":"Duygularımı tamamen hiçe saydı.","e2":"Please disregard my previous email.","e2t":"Lütfen önceki e"},{"w":"disrepair","tr":"bakımsızlık / haraplık","te":"Noun","tt":"İsim","de":"The state of being in bad condition because of neglect","dt":"İhmal nedeniyle kötü durumda olma hali","e1":"The house had fallen into disrepair.","e1t":"Ev bakımsızlıktan harap olmuştu.","e2":"A building in a state of disrepair.","e2t":"Bakımsız (harap) bir bina."},{"w":"disrepute","tr":"kötü ün / itibarsızlık","te":"Noun","tt":"İsim","de":"The state of being not respected or not trusted","dt":"Saygı görmeme veya güvenilmeme durumu","e1":"To bring the profession into disrepute.","e1t":"Mesleğin itibarını sarsmak (kötülemek).","e2":"To fall into disrepute.","e2t":"Gözden düşmek (itibarsızlaşmak)."},{"w":"disruptive","tr":"bozucu / engelleyici / yıkıcı","te":"Adjective","tt":"Sıfat","de":"Causing trouble and stopping something from continuing","dt":"Sorun çıkaran ve bir şeyin devam etmesini engelleyen","e1":"Disruptive behavior in the classroom.","e1t":"Sınıftaki engelleyici (bozucu) davranış.","e2":"A disruptive technology.","e2t":"Yıkıcı (düzen değiştiren) bir teknoloji."},{"w":"dissertation","tr":"tez / bilimsel inceleme","te":"Noun","tt":"İsim","de":"A long piece of writing on a particular subject for a degree","dt":"Akademik bir derece için belirli bir konuda yazılan uzun metin","e1":"He is writing his doctoral dissertation.","e1t":"Doktora tezini yazıyor.","e2":"A dissertation on history.","e2t":"Tarih üzerine bir tez."},{"w":"dissident","tr":"muhalif / karşı görüşlü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who publicly disagrees with the government","dt":"Hükümetle açıkça hemfikir olmayan kişi","e1":"Political dissidents.","e1t":"Siyasi muhalifler.","e2":"A dissident writer.","e2t":"Muhalif bir yazar."},{"w":"dissipate","tr":"dağıtmak / yok olmak / çarçur etmek","te":"Verb","tt":"Fiil","de":"To gradually disappear or waste","dt":"Yavaşça ortadan kaybolmak veya israf etmek","e1":"The fog eventually dissipated.","e1t":"Sis sonunda dağıldı.","e2":"To dissipate a fortune.","e2t":"Bir serveti çarçur etmek."},{"w":"dissonance","tr":"uyumsuzluk / ahenksizlik","te":"Noun","tt":"İsim","de":"A lack of agreement or harmony","dt":"Anlaşma veya uyum eksikliği","e1":"Cognitive dissonance (psychology).","e1t":"Bilişsel çelişki (uyumsuzluk).","e2":"Musical dissonance.","e2t":"Müzikal ahenksizlik (uyumsuzluk)."},{"w":"dissuade","tr":"caydırmak / vazgeçirmek","te":"Verb","tt":"Fiil","de":"To persuade someone not to do something","dt":"Birini bir şeyi yapmaması için ikna etmek","e1":"I tried to dissuade him from resigning.","e1t":"Onu istifa etmekten vazgeçirmeye çalıştım.","e2":"To dissuade someone from a plan.","e2t":"Birini bir plandan caydırmak."},{"w":"distasteful","tr":"nahoş / mide bulandırıcı / sevimsiz","te":"Adjective","tt":"Sıfat","de":"Unpleasant or offensive","dt":"Nahoş veya kırıcı","e1":"A distasteful remark.","e1t":"Nahoş (çirkin) bir söz.","e2":"I find his behavior distasteful.","e2t":"Davranışını sevimsiz (itici) buluyorum."},{"w":"distend","tr":"şişirmek / genişlemek / şişmek","te":"Verb","tt":"Fiil","de":"To swell or become larger due to pressure from inside","dt":"İçeriden gelen basınç nedeniyle şişmek veya büyümek","e1":"A distended stomach.","e1t":"Şişmiş bir karın.","e2":"The balloons distend when filled with air.","e2t":"Balonlar hava ile dolunca şişer."},{"w":"distill / distil","tr":"damıtmak / özünü çıkarmak","te":"Verb","tt":"Fiil","de":"To purify a liquid by boiling it; or to get the main ideas","dt":"Bir sıvıyı kaynatarak saflaştırmak; veya ana fikirleri süzmek (özünü çıkarmak)","e1":"Distilled water.","e1t":"Saf (damıtılmış) su.","e2":"To distill information from a report.","e2t":"Bir rapordan bilgileri süzmek."},{"w":"distraught","tr":"perişan / kendinden geçmiş / çok üzgün","te":"Adjective","tt":"Sıfat","de":"Extremely worried, nervous, or upset","dt":"Son derece endişeli, gergin veya üzgün","e1":"Distraught parents of the missing child.","e1t":"Kayıp çocuğun perişan haldeki ebeveynleri.","e2":"She was distraught with grief.","e2t":"Kederden kendinden geçmişti."},{"w":"diverge","tr":"ayrılmak / sapmak / farklılaşmak","te":"Verb","tt":"Fiil","de":"To follow a different direction; or to be different","dt":"Farklı bir yön izlemek; veya farklı olmak","e1":"The two paths diverge at the river.","e1t":"İki yol nehirde birbirinden ayrılıyor.","e2":"Our opinions began to diverge.","e2t":"Görüşlerimiz farklılaşmaya başladı."},{"w":"divest","tr":"yoksun bırakmak / elden çıkarmak / soyunmak","te":"Verb","tt":"Fiil","de":"To sell an asset; or to take away power or rights","dt":"Bir varlığı satmak; veya güç ya da hakları geri almak","e1":"The company decided to divest its chemical division.","e1t":"Şirket kimya bölümünü elden çıkarmaya (satmaya) karar verdi.","e2":"To divest someone of their authority.","e2t":"Birini yetkisinden yoksun bırakmak."},{"w":"divulge","tr":"ifşa etmek / açığa vurmak / sızdırmak","te":"Verb","tt":"Fiil","de":"To make something secret known","dt":"Gizli bir şeyi bilinir hale getirmek","e1":"I cannot divulge the source of my information.","e1t":"Bilgimin kaynağını ifşa edemem.","e2":"To divulge a secret.","e2t":"Bir sırrı açığa vurmak."},{"w":"docile","tr":"uysal / halim selim / kolay yönetilen","te":"Adjective","tt":"Sıfat","de":"Quiet and easy to influence or control","dt":"Sessiz ve etkilenmesi veya kontrol edilmesi kolay","e1":"A docile animal.","e1t":"Uysal bir hayvan.","e2":"The once rebellious students became docile.","e2t":"Bir zamanların asi öğrencileri uysallaştı."},{"w":"dogged","tr":"azimli / inatçı / kararlı","te":"Adjective","tt":"Sıfat","de":"Very determined to continue doing something","dt":"Bir şeyi yapmaya devam etmek için çok kararlı","e1":"Dogged determination.","e1t":"Sarsılmaz (inatçı) azim.","e2":"Her dogged efforts finally paid off.","e2t":"Azimli çabaları sonunda meyvesini verdi."},{"w":"dogmatic","tr":"katı görüşlü / dogmatik / dayatmacı","te":"Adjective","tt":"Sıfat","de":"Being certain that your beliefs are right and others are wrong","dt":"Kendi inançlarının doğru, diğerlerininkinin yanlış olduğundan emin olan","e1":"A dogmatic approach to religion.","e1t":"Dine dogmatik (katı) bir yaklaşım.","e2":"He is too dogmatic to listen to other ideas.","e2t":"Diğer fikirleri dinleyemeyecek kadar dayatmacıdır."},{"w":"doleful","tr":"hüzünlü / kederli / üzgün","te":"Adjective","tt":"Sıfat","de":"Very sad","dt":"Çok üzgün","e1":"A doleful expression.","e1t":"Kederli bir ifade.","e2":"Doleful music.","e2t":"Hüzünlü müzik."},{"w":"doting","tr":"aşırı sevgi gösteren / üzerine titreyen","te":"Adjective","tt":"Sıfat","de":"Showing extremely fond affection","dt":"Aşırı şefkat ve sevgi gösteren","e1":"A doting grandfather.","e1t":"Torununun üzerine titreyen (onu çok seven) dede.","e2":"Doting parents.","e2t":"Evlatlarına aşırı düşkün ebeveynler."},{"w":"dour","tr":"sert / soğuk / asık suratlı","te":"Adjective","tt":"Sıfat","de":"Unfriendly, unhappy, and very serious","dt":"Dostça olmayan, mutsuz ve çok ciddi","e1":"A dour expression.","e1t":"Asık (sert) bir surat ifadesi.","e2":"The dour landscape of the north.","e2t":"Kuzeyin soğuk (kasvetli) manzarası."},{"w":"downcast","tr":"morali bozuk / mahzun / (gözler) yere eğik","te":"Adjective","tt":"Sıfat","de":"Sad and without hope; or looking down","dt":"Üzgün ve umutsuz; veya aşağı bakan","e1":"He looked downcast after the meeting.","e1t":"Toplantıdan sonra morali bozuk görünüyordu.","e2":"With downcast eyes.","e2t":"Yere eğik gözlerle (mahcup bir şekilde)."},{"w":"downright","tr":"düpedüz / tamamen / doğrudan","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Extremely or completely (usually for something bad)","dt":"Aşırı veya tamamen (genellikle kötü bir durum için)","e1":"That’s a downright lie.","e1t":"Bu düpedüz bir yalan.","e2":"It was downright rude of him.","e2t":"Yaptığı düpedüz kabalıktı."},{"w":"drab","tr":"donuk / sıkıcı / kasvetli / gri","te":"kahverengi","tt":"Adjective/Noun","de":"Sıfat/İsim","dt":"Boring and without color","e1":"Sıkıcı ve renksiz","e1t":"A drab office building.","e2":"Sıkıcı (kasvetli) bir ofis binası.","e2t":"Drab colors."},{"w":"drastic","tr":"sert / güçlü / radikal / şiddetli","te":"Adjective","tt":"Sıfat","de":"Sudden and severe","dt":"Ani ve şiddetli","e1":"Drastic measures.","e1t":"Sert (radikal) önlemler.","e2":"A drastic change in the climate.","e2t":"İklimde sert bir değişim."},{"w":"dregs","tr":"tortu / dip / en değersiz kısım","te":"Noun","tt":"İsim","de":"The small amount of liquid and solid left at the bottom; or the worst part","dt":"Dipte kalan az miktar sıvı ve katı; veya en kötü kısım","e1":"The dregs of the coffee.","e1t":"Kahvenin tortusu (telvesi).","e2":"The dregs of society.","e2t":"Toplumun en alt (değersiz) tabakası."},{"w":"droll","tr":"garip ama komik / nükteli / tuhaf","te":"Adjective","tt":"Sıfat","de":"Humorous in an unusual or unexpected way","dt":"Olağandışı veya beklenmedik bir şekilde komik","e1":"A droll sense of humor.","e1t":"Garip (nükteli) bir mizah anlayışı.","e2":"He made a droll remark.","e2t":"Tuhaf ama komik bir yorum yaptı."},{"w":"drone","tr":"vızıldamak / monoton konuşmak / insansız hava aracı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A low continuous humming sound; or an aircraft without a pilot","dt":"Alçak ve sürekli vızıldama sesi; veya insansız hava aracı","e1":"The drone of an engine.","e1t":"Motorun vızıltısı.","e2":"He d roned on for hours.","e2t":"Saatlerce monoton bir şekilde konuştu."},{"w":"drowsy","tr":"uykulu / mahmur / uyku getiren","te":"Adjective","tt":"Sıfat","de":"Feeling tired and wanting to sleep","dt":"Yorgun hissetme ve uyuma isteği","e1":"The medicine made me feel drowsy.","e1t":"İlaç uykumu getirdi (beni mahmurlaştırdı).","e2":"A drowsy afternoon.","e2t":"Rehavet çökmüş (uykulu) bir öğleden sonra."},{"w":"drudgery","tr":"angarya iş / zahmetli ve sıkıcı iş","te":"Noun","tt":"İsim","de":"Hard boring work","dt":"Zor ve sıkıcı iş","e1":"The drudgery of housework.","e1t":"Ev işlerinin angaryası (sıkıcılığı).","e2":"A life of drudgery.","e2t":"Zahmetli ve tekdüze bir hayat."},{"w":"ductile","tr":"şekillendirilebilir / sünek / uysal","te":"Adjective","tt":"Sıfat","de":"(Of a metal) able to be drawn out into a thin wire","dt":"(Metal için) ince tel haline getirilebilen; sünek","e1":"Gold is a very ductile metal.","e1t":"Altın çok sünek (şekillendirilebilir) bir metaldir.","e2":"A ductile personality.","e2t":"Uysal (eğilip bükülebilen) bir kişilik."},{"w":"duplicity","tr":"ikiyüzlülük / hilekarlık","te":"Noun","tt":"İsim","de":"Dishonest behavior that is intended to deceive","dt":"Aldatmaya yönelik dürüst olmayan davranış","e1":"He was accused of duplicity in his business dealings.","e1t":"Ticari ilişkilerinde ikiyüzlülükle suçlandı.","e2":"Political duplicity.","e2t":"Siyasi hilekarlık."},{"w":"duress","tr":"baskı / zorlama","te":"Noun","tt":"İsim","de":"Threats used to force someone to do something","dt":"Birini bir şeye zorlamak için kullanılan tehditler","e1":"He signed the confession under duress.","e1t":"İtirafı baskı (zorlama) altında imzaladı.","e2":"To act under duress.","e2t":"Zorlama altında hareket etmek."},{"w":"dwindle","tr":"gitgide azalmak / küçülmek / tükenmek","te":"Verb","tt":"Fiil","de":"To become smaller in size or amount, or fewer in number","dt":"Boyut, miktar veya sayıca küçülmek/azalmak","e1":"Resources are dwindling rapidly.","e1t":"Kaynaklar hızla tükeniyor (azalıyor).","e2":"Her hopes began to dwindle.","e2t":"Umutları azalmaya başladı."},{"w":"dysfunctional","tr":"işlevsiz / bozuk / görevini yapamayan","te":"Adjective","tt":"Sıfat","de":"Not behaving or working normally","dt":"Normal şekilde davranmayan veya çalışmayan","e1":"A dysfunctional family.","e1t":"Sorunlu (işlevsiz) bir aile.","e2":"A dysfunctional legal system.","e2t":"İşlemeyen (bozuk) bir hukuk sistemi."},{"w":"earmark","tr":"tahsis etmek / ayırmak / işaret","te":"Verb/Noun","tt":"Fiil/İsim","de":"To keep or intend something for a particular purpose","dt":"Bir şeyi belirli bir amaç için ayırmak veya niyet etmek","e1":"The money was earmarked for education.","e1t":"Para eğitim için tahsis edildi (ayrıldı).","e2":"To earmark a site for a new hospital.","e2t":"Bir alanı yeni hastane için belirlemek."},{"w":"earthly","tr":"dünyevi / dünya ile ilgili / mümkün","te":"Adjective","tt":"Sıfat","de":"Relating to the world rather than to spiritual things","dt":"Ruhani şeylerden ziyade dünya ile ilgili","e1":"Earthly pleasures.","e1t":"Dünyevi zevkler.","e2":"There is no earthly reason to worry.","e2t":"Endişelenmek için (dünyada) hiçbir sebep yok."},{"w":"eavesdrop","tr":"gizlice dinlemek / kulak misafiri olmak","te":"Verb","tt":"Fiil","de":"To listen to someone's private conversation without them knowing","dt":"Birinin özel konuşmasını haberi olmadan dinlemek","e1":"He was caught eavesdropping on our conversation.","e1t":"Konuşmamızı gizlice dinlerken yakalandı.","e2":"To eavesdrop at the door.","e2t":"Kapıdan kulak misafiri olmak."},{"w":"ebb","tr":"çekilmek (gelgit) / azalmak / gerileme","te":"Noun/Verb","tt":"İsim/Fiil","de":"(Of the sea) to move away from the coast; or to become less","dt":"(Deniz için) kıyıdan uzaklaşmak; veya azalmak","e1":"The tide is on the ebb.","e1t":"Gelgit çekiliyor.","e2":"His confidence was at a low ebb.","e2t":"Özgüveni en düşük seviyesindeydi (gerilemişti)."},{"w":"eclectic","tr":"çeşitli kaynaklardan derlenen / seçmeci","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Including things from many different sources or styles","dt":"Birçok farklı kaynak veya tarzdan öğeler içeren","e1":"An eclectic mix of music.","e1t":"Farklı tarzlardan oluşan (eklektik) bir müzik karışımı.","e2":"Her taste in art is very eclectic.","e2t":"Sanat zevki çok çeşitlidir (karma)."},{"w":"ecstatic","tr":"çok mutlu / kendinden geçmiş / mest olmuş","te":"Adjective","tt":"Sıfat","de":"Extremely happy","dt":"Son derece mutlu","e1":"The crowd was ecstatic.","e1t":"Kalabalık mest olmuştu (çok mutluydu).","e2":"She was ecstatic about her new job.","e2t":"Yeni işi için havalara uçuyordu."},{"w":"edict","tr":"emir / ferman / kararname","te":"Noun","tt":"Isim","de":"An official order given by a person in authority","dt":"Yetkili bir kişi tarafından verilen resmi emir","e1":"The government issued an edict banning public gatherings.","e1t":"Hükümet toplu buluşmaları yasaklayan bir emir (kararname) çıkardı.","e2":"To rule by edict.","e2t":"Fermanla yönetmek."},{"w":"edifying","tr":"öğretici / geliştirici / faydalı","te":"Adjective","tt":"Sıfat","de":"Improving your mind or character","dt":"Zihni veya karakteri geliştiren (eğitici)","e1":"An edifying experience.","e1t":"Geliştirici (öğretici) bir deneyim.","e2":"Not a very edifying sight (ironic).","e2t":"Pek de hoş/örnek olmayan bir manzara."},{"w":"efface","tr":"silmek / yok etmek / kendini geri çekmek","te":"Verb","tt":"Fiil","de":"To remove something intentionally; or to make yourself unnoticeable","dt":"Bir şeyi kasten silmek; veya kendini fark edilmez kılmak","e1":"To efface a memory.","e1t":"Bir anıyı silmek.","e2":"He tried to efface himself in the crowd.","e2t":"Kalabalığın içinde kendini unutturmaya (gizlemeye) çalıştı."},{"w":"effectual","tr":"etkili / geçerli / sonuç veren","te":"Adjective","tt":"Sıfat","de":"Successful in producing the intended results","dt":"Amaçlanan sonuçları üretmede başarılı","e1":"An effectual remedy.","e1t":"Etkili bir çözüm (ilaç).","e2":"The law was not very effectual.","e2t":"Yasa pek etkili (sonuç verici) değildi."},{"w":"efficacy","tr":"etkililik / yarar / tesir","te":"Noun","tt":"İsim","de":"The ability to produce the intended result","dt":"Amaçlanan sonucu üretme yeteneği","e1":"To test the efficacy of a new drug.","e1t":"Yeni bir ilacın etkililiğini test etmek.","e2":"The policy has little efficacy.","e2t":"Politikanın etkisi (yararı) çok az."},{"w":"effigy","tr":"kukla (protesto amaçlı) / heykel / suret","te":"Noun","tt":"İsim","de":"A model of a person, especially one that is burned in protest","dt":"Bir kişinin modeli, özellikle protesto için yakılan kuklası","e1":"The protesters burned an effigy of the president.","e1t":"Protestocular başkanın bir kuklasını yaktı.","e2":"Stone effigies in the cathedral.","e2t":"Katedraldeki taş heykeller."},{"w":"effrontery","tr":"küstahlık / arsızlık / hayasızlık","te":"Noun","tt":"İsim","de":"Extreme rudeness without any shame","dt":"Utanma olmaksızın gösterilen aşırı kabalık","e1":"He had the effrontery to ask for more money.","e1t":"Daha fazla para isteme küstahlığında bulundu.","e2":"Such effrontery is hard to believe.","e2t":"Bu kadar arsızlığa inanmak zor."},{"w":"effusive","tr":"taşkın duygulu / coşkulu / aşırı","te":"Adjective","tt":"Sıfat","de":"Expressing welcome or approval in a very enthusiastic way","dt":"Karşılamayı veya onayı çok hevesli bir şekilde ifade eden","e1":"An effusive welcome.","e1t":"Coşkulu (taşkın) bir karşılama.","e2":"She was effusive in her praise.","e2t":"Övgüsünde çok aşırıya kaçtı (coşkuluydu)."},{"w":"egalitarian","tr":"eşitlikçi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Based on the idea that people are equal and should be treated equally","dt":"İnsanların eşit olduğu ve eşit davranılması gerektiği fikrine dayanan","e1":"An egalitarian society.","e1t":"Eşitlikçi bir toplum.","e2":"Egalitarian principles.","e2t":"Eşitlikçi ilkeler."},{"w":"egocentric","tr":"bencil / benmerkezci","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Thinking only about yourself and not about others","dt":"Sadece kendisini düşünen, başkalarını önemsemeyen","e1":"An egocentric child.","e1t":"Benmerkezci bir çocuk.","e2":"His egocentric behavior.","e2t":"Onun bencilce davranışı."},{"w":"elaborate","tr":"detaylı / ayrıntılı / özenli / detaylandırmak","te":"Adjective/Verb","tt":"Containing a lot of careful detail; or to explain more","de":"Çok sayıda dikkatli detay içeren; veya daha fazla açıklamak","dt":"An elaborate plan.","e1":"Detaylı (ayrıntılı) bir plan.","e1t":"Could you elaborate on that?","e2":"Bunu biraz daha detaylandırabilir misiniz?","e2t":""},{"w":"elapse","tr":"geçmek (zaman)","te":"Verb","tt":"Fiil","de":"(Of time) to go past","dt":"(Zaman için) geçip gitmek","e1":"Four years had elapsed since he left.","e1t":"O gittiğinden beri dört yıl geçmişti.","e2":"A significant amount of time elapsed.","e2t":"Önemli miktarda zaman geçti."},{"w":"elated","tr":"çok mutlu / sevinçten havalara uçmuş","te":"Adjective","tt":"Sıfat","de":"Extremely happy and excited","dt":"Son derece mutlu ve heyecanlı","e1":"He was elated by the news of his victory.","e1t":"Zafer haberiyle sevinçten havalara uçtu.","e2":"The elated winner.","e2t":"Çok mutlu kazanan."},{"w":"electorate","tr":"seçmen kitlesi","te":"Noun","tt":"İsim","de":"All the people who are allowed to vote","dt":"Oy kullanma hakkı olan tüm insanlar","e1":"The electorate will decide on Sunday.","e1t":"Seçmenler Pazar günü karar verecek.","e2":"To appeal to the electorate.","e2t":"Seçmen kitlesine hitap etmek."},{"w":"elicit","tr":"ortaya çıkarmak / temin etmek / (tepki) uyandırmak","te":"Verb","tt":"Fiil","de":"To get information or a reaction from someone","dt":"Birinden bilgi veya tepki almak (sağlamak)","e1":"To elicit a response.","e1t":"Bir tepki almak (uyandırmak).","e2":"The questionnaire was intended to elicit information on eating habits.","e2t":"Anket, beslenme alışkanlıkları hakkında bilgi edinmeyi amaçlıyordu."},{"w":"elocution","tr":"hitabet sanatı / güzel konuşma","te":"Noun","tt":"İsim","de":"The art of careful public speaking","dt":"Topluluk önünde dikkatli ve güzel konuşma sanatı","e1":"Elocution lessons.","e1t":"Hitabet dersleri.","e2":"To have good elocution.","e2t":"Hitabeti (diksiyonu) iyi olmak."},{"w":"elude","tr":"kaçmak / kurtulmak / aklına gelmemek","te":"Verb","tt":"Fiil","de":"To escape from or avoid, typically in a skillful way","dt":"Genellikle becerikli bir şekilde kaçmak veya kurtulmak","e1":"The thief eluded the police for weeks.","e1t":"Hırsız haftalarca polisten kaçtı (kurtuldu).","e2":"His name eludes me.","e2t":"İsmi bir türlü aklıma gelmiyor."},{"w":"elusive","tr":"yakalanması zor / ele geçmez / tarifi imkansız","te":"Adjective","tt":"Sıfat","de":"Difficult to describe, find, achieve, or remember","dt":"Tanımlanması, bulunması, başarılması veya hatırlanması zor","e1":"Success remained elusive for him.","e1t":"Başarı onun için hala ulaşılamazdı (ele geçmezdi).","e2":"An elusive criminal.","e2t":"Yakalanması zor bir suçlu."},{"w":"emaciated","tr":"aşırı zayıf / bir deri bir kemik","te":"Adjective","tt":"Sıfat","de":"Very thin and weak, usually because of illness or lack of food","dt":"Genellikle hastalık veya açlıktan dolayı çok zayıf ve güçsüz","e1":"Emaciated prisoners of war.","e1t":"Bir deri bir kemik kalmış savaş esirleri.","e2":"He looked emaciated after the long illness.","e2t":"Uzun süren hastalıktan sonra aşırı zayıf görünüyordu."},{"w":"emanate","tr":"yayılmak / çıkmak / sızmak","te":"Verb","tt":"Fiil","de":"To come from or out of something","dt":"Bir şeyden gelmek veya çıkmak","e1":"Light emanates from the sun.","e1t":"Işık güneşten yayılır.","e2":"A strange smell emanated from the kitchen.","e2t":"Mutfaktan tuhaf bir koku geliyordu (yayılıyordu)."},{"w":"emancipate","tr":"özgürleştirmek / serbest bırakmak","te":"Verb","tt":"Fiil","de":"To give people social or political freedom","dt":"İnsanlara sosyal veya siyasi özgürlük vermek","e1":"To emancipate slaves.","e1t":"Köleleri özgürleştirmek.","e2":"Women's emancipation.","e2t":"Kadınların özgürleşmesi."},{"w":"embellish","tr":"süslemek / donatmak / (hikayeye) yalan katmak","te":"Verb","tt":"Fiil","de":"To make something more beautiful; or to add false details to a story","dt":"Bir şeyi daha güzel yapmak; veya bir hikayeye yanlış detaylar eklemek","e1":"The walls were embellished with gold.","e1t":"Duvarlar altınla süslenmişti.","e2":"He embellished the story to make it more exciting.","e2t":"Hikayeyi daha heyecanlı kılmak için (yalanlarla) süsledi."},{"w":"embezzle","tr":"zimmete para geçirmek / çalmak","te":"Verb","tt":"Fiil","de":"To secretly take money that belongs to an organization you work for","dt":"Çalışılan kuruma ait parayı gizlice kendi üstüne geçirmek","e1":"He was caught embezzling funds from the bank.","e1t":"Banka fonlarını zimmetine geçirirken yakalandı.","e2":"To embezzle public money.","e2t":"Kamu parasını iç etmek (zimmete geçirmek)."},{"w":"embody","tr":"somutlaştırmak / temsil etmek / bünyesinde toplamak","te":"Verb","tt":"Fiil","de":"To represent a quality or an idea exactly","dt":"Bir niteliği veya fikri tam olarak temsil etmek (vücut buldurmak)","e1":"She embodies everything a good teacher should be.","e1t":"İyi bir öğretmenin olması gereken her şeyi kendinde topluyor (temsil ediyor).","e2":"The new law embodies these principles.","e2t":"Yeni yasa bu ilkeleri somutlaştırıyor."},{"w":"embroil","tr":"dahil etmek (karmaşaya) / bulaştırmak / karıştırmak","te":"Verb","tt":"Fiil","de":"To cause someone to become involved in an argument or difficult situation","dt":"Birini bir tartışmaya veya zor bir duruma dahil etmek","e1":"He became embroiled in a legal dispute.","e1t":"Bir hukuk savaşının (ihtilafın) içine çekildi.","e2":"To be embroiled in a scandal.","e2t":"Bir skandala karışmak."},{"w":"emergent","tr":"ortaya çıkan / yeni gelişen","te":"Adjective","tt":"Sıfat","de":"Starting to exist or to become known","dt":"Var olmaya veya bilinir hale gelmeye başlayan","e1":"Emergent economies.","e1t":"Gelişmekte olan (yeni çıkan) ekonomiler.","e2":"An emergent talent.","e2t":"Yeni ortaya çıkan bir yetenek."},{"w":"emigrate","tr":"göç etmek (başka bir ülkeye)","te":"Verb","tt":"Fiil","de":"To leave your own country to go and live permanently in another","dt":"Kendi ülkesinden ayrılıp kalıcı olarak başka bir ülkeye yerleşmek","e1":"My grandparents emigrated from Turkey to Germany.","e1t":"Büyükannem ve büyükbabam Türkiye'den Almanya'ya göç ettiler.","e2":"To emigrate for a better life.","e2t":"Daha iyi bir yaşam için göç etmek."},{"w":"eminence","tr":"yücelik / üstünlük / seçkinlik","te":"Noun","tt":"İsim","de":"The state of being famous, respected, or important","dt":"Ünlü, saygın veya önemli olma durumu","e1":"A man of great eminence in his profession.","e1t":"Mesleğinde büyük saygınlığa (seçkinliğe) sahip bir adam.","e2":"To reach eminence.","e2t":"Yüceliğe (başarıya) ulaşmak."},{"w":"emissary","tr":"elçi / özel temsilci / uşak","te":"Noun","tt":"İsim","de":"A person sent by a government or leader to deliver a message","dt":"Bir mesaj iletmek üzere bir hükümet veya lider tarafından gönderilen kişi","e1":"A confidential emissary.","e1t":"Gizli bir elçi (temsilci).","e2":"To send an emissary to negotiate peace.","e2t":"Barışı müzakere etmek için bir elçi göndermek."},{"w":"emulate","tr":"taklit etmek / öykünmek / yarışmak","te":"Verb","tt":"Fiil","de":"To copy something achieved by someone else and try to do it as well as they have","dt":"Başkasının başarısını kopyalamak ve en az onun kadar iyi yapmaya çalışmak","e1":"They hope to emulate the success of other companies.","e1t":"Diğer şirketlerin başarısını yakalamayı (öykünmeyi) umuyorlar.","e2":"A son emulating his father.","e2t":"Babasını örnek alan (taklit eden) bir oğul."},{"w":"encomium","tr":"övgü / methiye","te":"Noun","tt":"İsim","de":"A piece of writing or speech that praises someone highly (formal)","dt":"Birini yüksek derecede öven yazı veya konuşma (resmi)","e1":"An encomium to the fallen heroes.","e1t":"Şehit kahramanlara yazılmış bir methiye.","e2":"To deliver an encomium.","e2t":"Övgü dolu bir konuşma yapmak."},{"w":"encompass","tr":"kapsamak / çevrelemek / kuşatmak","te":"Verb","tt":"Fiil","de":"To include different types of things; or to surround","dt":"Farklı türde şeyleri içermek; veya etrafını sarmak","e1":"The festival encompasses everything from music to food.","e1t":"Festival, müzikten yemeğe kadar her şeyi kapsıyor.","e2":"The fog encompassed the mountains.","e2t":"Sis dağları kuşattı (çevreledi)."},{"w":"encore","tr":"yeniden sahneye çağrı / bis","te":"Noun/Interjection","tt":"An extra song or performance that an audience asks for","de":"Dinleyicinin isteği üzerine yapılan ekstra performans veya şarkı","dt":"The band played three encores.","e1":"Grup üç kez bis yaptı (ekstra şarkı çaldı).","e1t":"\"Encore!\" shouted the crowd.","e2":"Kalabalık \"Tekrar!\" diye bağırdı.","e2t":""},{"w":"encroach","tr":"müdahale etmek / tecavüz etmek / sınırını aşmak","te":"Verb","tt":"Fiil","de":"To gradually take away someone else's rights, or to move into their area","dt":"Başkasının haklarını yavaşça elinden almak veya alanına girmek","e1":"The sea is encroaching on the land.","e1t":"Deniz karaya doğru ilerliyor (karayı aşındırıyor).","e2":"To encroach on someone's privacy.","e2t":"Birinin mahremiyetine müdahale etmek (sınırı aşmak)."},{"w":"enervate","tr":"güçsüzleştirmek / enerjisini tüketmek / bitkin düşürmek","te":"Verb","tt":"Fiil","de":"To make someone feel weak and without energy","dt":"Birini zayıf ve enerjisiz hissettirmek","e1":"The hot sun enervated the runners.","e1t":"Sıcak güneş koşucuları bitkin düşürdü.","e2":"Enervating humidity.","e2t":"Enerji tüketen (baygınlık veren) nem."},{"w":"enfranchise","tr":"oy hakkı vermek / özgür bırakmak","te":"Verb","tt":"Fiil","de":"To give a person or group of people the right to vote","dt":"Bir kişi veya gruba oy kullanma hakkı tanımak","e1":"Women were finally enfranchised in 1934.","e1t":"Kadınlara sonunda 1934'te oy hakkı verildi.","e2":"To enfranchise a slave.","e2t":"Bir köleyi özgür bırakmak."},{"w":"engender","tr":"neden olmak / doğurmak / uyandırmak","te":"Verb","tt":"Fiil","de":"To cause or produce a feeling or situation","dt":"Bir duyguya veya duruma neden olmak","e1":"The changes engendered a lot of controversy.","e1t":"Değişiklikler birçok tartışmaya neden oldu (tartışma doğurdu).","e2":"To engender confidence.","e2t":"Güven uyandırmak."},{"w":"enigma","tr":"gizem / muamma / bilmece","te":"Noun","tt":"İsim","de":"Something that is mysterious and difficult to understand","dt":"Gizemli ve anlaşılması zor olan şey","e1":"He is an enigma to his colleagues.","e1t":"Meslektaşları için bir muammadır.","e2":"To solve the enigma.","e2t":"Bilmeceyi (gizemi) çözmek."},{"w":"enigmatic","tr":"esrarengiz / gizemli / kapalı","te":"Adjective","tt":"Sıfat","de":"Mysterious and impossible to understand completely","dt":"Tamamen anlaşılması imkansız ve gizemli","e1":"An enigmatic smile.","e1t":"Esrarengiz (gizemli) bir gülümseme.","e2":"He left an enigmatic message.","e2t":"Kapalı (gizemli) bir mesaj bıraktı."},{"w":"enjoin","tr":"emretmek / yasaklamak (hukuk) / telkin etmek","te":"Verb","tt":"Fiil","de":"To officially order someone to do something; or to prevent (legal)","dt":"Birine bir şeyi yapmasını resmi olarak emretmek veya (hukuken) yasaklamak","e1":"The judge enjoined them from selling the property.","e1t":"Hakim onların mülkü satmasını yasakladı (men etti).","e2":"To enjoin secrecy.","e2t":"Gizlilik emretmek (telkin etmek)."},{"w":"enlist","tr":"kaydolmak (ordu vb.) / yardımını almak / askere yazılmak","te":"Verb","tt":"Fiil","de":"To join the armed forces; or to ask for help","dt":"Silahlı kuvvetlere katılmak; veya yardım istemek","e1":"He enlisted in the navy.","e1t":"Donanmaya yazıldı.","e2":"We need to enlist the support of the local community.","e2t":"Yerel halkın desteğini almamız (sağlamamız) gerekiyor."},{"w":"enliven","tr":"canlandırmak / neşelendirmek / renk katmak","te":"Verb","tt":"Fiil","de":"To make something more interesting or exciting","dt":"Bir şeyi daha ilginç veya heyecanlı hale getirmek","e1":"Humour helped enliven the lecture.","e1t":"Mizah, dersi canlandırmaya yardımcı oldu.","e2":"To enliven a party.","e2t":"Bir partiye renk katmak."},{"w":"enormity","tr":"büyüklük (olumsuz) / canavarlık / iğrençlik","te":"Noun","tt":"İsim","de":"The great size of something bad; or a very evil act","dt":"Kötü bir şeyin devasa boyutu; veya çok kötü bir eylem","e1":"The enormity of the crime shocked the nation.","e1t":"Suçun iğrençliği (büyüklüğü) ulusu şok etti.","e2":"We realized the enormity of the task.","e2t":"Görevin muazzamlığını (zorluğunu) fark ettik."},{"w":"enrage","tr":"öfkelendirmek / çileden çıkarmak","te":"Verb","tt":"Fiil","de":"To make someone extremely angry","dt":"Birini aşırı derecede kızdırmak","e1":"The decision enraged the local residents.","e1t":"Karar, bölge sakinlerini çileden çıkardı.","e2":"He was enraged by the insults.","e2t":"Hakaretler onu öfkelendirdi."},{"w":"ensconce","tr":"yerleştirmek / kurulmak / sığınmak","te":"Verb","tt":"Fiil","de":"To settle oneself comfortably and safely in a place","dt":"Bir yere rahatça ve güvenle yerleşmek","e1":"He was ensconced in his favorite armchair.","e1t":"En sevdiği koltuğuna kurulmuştu.","e2":"To be ensconced in a new job.","e2t":"Yeni bir işe (güvenle) yerleşmek."},{"w":"ensemble","tr":"topluluk / grup / takım (giysi)","te":"Noun","tt":"İsim","de":"A group of musicians or actors who perform together; or an outfit","dt":"Birlikte performans sergileyen müzisyen veya oyuncu grubu; veya kıyafet takımı","e1":"A brass ensemble.","e1t":"Pirinç üflemeli çalgılar topluluğu.","e2":"She was wearing a stylish blue ensemble.","e2t":"Şık mavi bir takım giyiyordu."},{"w":"enthrall","tr":"büyülemek / esir etmek / hayran bırakmak","te":"Verb","tt":"Fiil","de":"To keep someone's interest and delight them completely","dt":"Birinin ilgisini sürekli canlı tutmak ve onu mest etmek","e1":"I was enthralled by the beauty of the city.","e1t":"Şehrin güzelliği karşısında büyülendim.","e2":"An enthralling book.","e2t":"Sürükleyici (büyüleyici) bir kitap."},{"w":"entitled","tr":"hak sahibi / unvanlı / kendini hak sahibi gören (şımarık)","te":"Adjective","tt":"Sıfat","de":"Having the right to do or have something; or feeling superior","dt":"Bir şeyi yapma/alma hakkı olan; veya kendini üstün gören","e1":"Everyone is entitled to a fair trial.","e1t":"Herkes adil yargılanma hakkına sahiptir.","e2":"He's so entitled (thinks he deserves everything).","e2t":"Çok şımarık (her şeyin kendi hakkı olduğunu sanıyor)."},{"w":"entity","tr":"varlık / birim / mevcudiyet","te":"Noun","tt":"İsim","de":"Something that exists apart from other things, having its own independent existence","dt":"Kendi başına var olan, diğerlerinden ayrı olan şey","e1":"The company is a separate legal entity.","e1t":"Şirket ayrı bir tüzel kişiliktir.","e2":"A commercial entity.","e2t":"Ticari bir varlık."},{"w":"entreat","tr":"yalvarmak / istirham etmek","te":"Verb","tt":"Fiil","de":"To ask someone in a very emotional way","dt":"Çok duygusal ve ısrarlı bir şekilde birinden bir şey istemek","e1":"She entreated him to help her.","e1t":"Ona yardım etmesi için yalvardı.","e2":"I entreat you to stay.","e2t":"Kalmanız için size yalvarıyorum."},{"w":"enumerate","tr":"numaralandırmak / tek tek saymak","te":"Verb","tt":"Fiil","de":"To name things separately, one by one","dt":"Şeyleri tek tek, sırayla isimlendirmek","e1":"He enumerated the benefits of the new system.","e1t":"Yeni sistemin faydalarını tek tek saydı.","e2":"To enumerate a list.","e2t":"Bir listeyi maddeler halinde sıralamak."},{"w":"enunciate","tr":"açıkça söylemek / telaffuz etmek / (fikir) beyan etmek","te":"Verb","tt":"Fiil","de":"To pronounce words clearly; or to express an idea clearly","dt":"Kelimeleri net telaffuz etmek; veya bir fikri netçe ifade etmek","e1":"You must learn to enunciate your words.","e1t":"Kelimeleri net telaffuz etmeyi öğrenmelisin.","e2":"To enunciate a theory.","e2t":"Bir teoriyi açıkça ortaya koymak."},{"w":"envoy","tr":"elçi / temsilci / murahhas","te":"Noun","tt":"İsim","de":"A person sent to represent a government or country","dt":"Bir hükümeti veya ülkeyi temsil etmek üzere gönderilen kişi","e1":"A special envoy to the Middle East.","e1t":"Orta Doğu özel temsilcisi (elçisi).","e2":"Diplomatic envoy.","e2t":"Diplomatik elçi."},{"w":"enzyme","tr":"enzim","te":"Noun","tt":"İsim","de":"A chemical substance that helps a chemical change happen","dt":"Kimyasal bir değişimin gerçekleşmesine yardımcı olan kimyasal madde","e1":"Digestive enzymes.","e1t":"Sindirim enzimleri.","e2":"Enzymes help break down food.","e2t":"Enzimler yiyeceklerin parçalanmasına yardımcı olur."},{"w":"ephemeral","tr":"geçici / kısa ömürlü / fani","te":"Adjective","tt":"Sıfat","de":"Lasting for only a short time","dt":"Sadece kısa bir süre süren","e1":"Fame is ephemeral.","e1t":"Şöhret geçicidir (fani).","e2":"Ephemeral pleasures.","e2t":"Gelip geçici zevkler."},{"w":"epic","tr":"destansı / epik / çok büyük","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A long film or book about exciting events; or very impressive","dt":"Heyecan verici olaylar hakkındaki uzun film/kitap; veya çok etkileyici","e1":"An epic journey.","e1t":"Destansı bir yolculuk.","e2":"A movie epic.","e2t":"Film destanı (devasa yapım)."},{"w":"epidermis","tr":"deri üst tabakası / dış deri","te":"Noun","tt":"İsim","de":"The thin outer layer of the skin","dt":"Derinin ince dış tabakası","e1":"The epidermis protects the body.","e1t":"Üst deri vücudu korur.","e2":"Epidermal cells.","e2t":"Epiderma hücreleri."},{"w":"epigram","tr":"özlü söz / nükte","te":"Noun","tt":"İsim","de":"A short saying or poem which is clever and funny","dt":"Zekice ve komik olan kısa söz veya şiir","e1":"Oscar Wilde was famous for his epigrams.","e1t":"Oscar Wilde özlü sözleriyle (nükteleriyle) ünlüydü.","e2":"A witty epigram.","e2t":"Zekice bir özlü söz."},{"w":"epiphany","tr":"aydınlanma anı / idrak / vahiy","te":"Noun","tt":"İsim","de":"A moment when you suddenly understand something important","dt":"Önemli bir şeyi aniden anladığınız an","e1":"I had an epiphany and realized what I wanted to do.","e1t":"Bir aydınlanma anı yaşadım ve ne yapmak istediğimi anladım.","e2":"A sudden epiphany.","e2t":"Ani bir idrak."},{"w":"episodic","tr":"bölümlere ayrılmış / ara sıra olan / epizodik","te":"Adjective","tt":"Sıfat","de":"Happening only sometimes and not regularly; or in parts","dt":"Sadece bazen ve düzensiz olan; veya bölümler halinde olan","e1":"An episodic memory.","e1t":"Anısal (epizodik) hafıza.","e2":"The disease has an episodic nature.","e2t":"Hastalık nöbetler halinde (ara sıra) seyrediyor."},{"w":"epitaph","tr":"mezar yazısı / kitabe","te":"Noun","tt":"İsim","de":"Something written on a gravestone","dt":"Mezar taşına yazılan yazı","e1":"A moving epitaph to a great leader.","e1t":"Büyük bir lider için duygulandırıcı bir mezar yazısı.","e2":"To write an epitaph.","e2t":"Bir mezar kitabesi yazmak."},{"w":"epitome","tr":"öz / en iyi örnek / timsal","te":"Noun","tt":"İsim","de":"The best possible example of a particular quality","dt":"Belirli bir niteliğin mümkün olan en iyi örneği","e1":"She is the epitome of kindness.","e1t":"O, nazikliğin timsalidir (özüdür).","e2":"The epitome of a modern city.","e2t":"Modern bir şehrin mükemmel örneği."},{"w":"equanimity","tr":"sükunet / itidal / soğukkanlılık","te":"Noun","tt":"İsim","de":"A calm state of mind, especially in a difficult situation","dt":"Özellikle zor bir durumda sakin kalma hali","e1":"He received the bad news with equanimity.","e1t":"Kötü haberi sükunetle (itidalle) karşıladı.","e2":"To maintain your equanimity.","e2t":"Soğukkanlılığını korumak."},{"w":"equitable","tr":"adil / hakkaniyetli / tarafsız","te":"Adjective","tt":"Sıfat","de":"Fair and reasonable; treating everyone the same","dt":"Adil ve makul; herkese aynı şekilde davranan","e1":"An equitable distribution of wealth.","e1t":"Gelirin adil dağılımı.","e2":"We need an equitable solution.","e2t":"Hakkaniyetli bir çözüme ihtiyacımız var."},{"w":"equivocal","tr":"iki anlama gelebilen / belirsiz / şüpheli","te":"Adjective","tt":"Sıfat","de":"Not clear and seeming to have two meanings; or intentionaly vague","dt":"Net olmayan ve iki anlamlı görünen; veya kasten belirsiz","e1":"He gave an equivocal answer.","e1t":"Kaçamak (belirsiz) bir cevap verdi.","e2":"Equivocal results.","e2t":"Şüpheli (net olmayan) sonuçlar."},{"w":"erotic","tr":"cinsel içerikli / erotik / şehvet uyandıran","te":"Adjective","tt":"Sıfat","de":"Relating to sexual desire or excitement","dt":"Cinsel arzu veya heyecanla ilgili","e1":"Erotic art.","e1t":"Erotik sanat.","e2":"An erotic novel.","e2t":"Erotik bir roman."},{"w":"erratic","tr":"düzensiz / değişken / kararsız / tutarsız","te":"Adjective","tt":"Sıfat","de":"Not regular or consistent and changing often","dt":"Düzenli olmayan ve sık sık değişen","e1":"His behavior has become increasingly erratic.","e1t":"Davranışları giderek daha tutarsız (değişken) bir hal aldı.","e2":"Erratic breathing.","e2t":"Düzensiz soluk alıp verme."},{"w":"erroneous","tr":"hatalı / yanlış / kusurlu","te":"Adjective","tt":"Sıfat","de":"Wrong or false","dt":"Yanlış veya sahte","e1":"Erroneous information.","e1t":"Hatalı bilgi.","e2":"Based on an erroneous assumption.","e2t":"Yanlış bir varsayıma dayalı."},{"w":"erstwhile","tr":"eski / önceki / bir zamanki","te":"Adjective","tt":"Sıfat","de":"Former; in the past (formal)","dt":"Eski; geçmişteki (resmi)","e1":"His erstwhile friends.","e1t":"Onun eski arkadaşları.","e2":"An erstwhile professor.","e2t":"Eski bir profesör."},{"w":"erudite","tr":"çok bilgili / alim / bilge","te":"Adjective","tt":"Sıfat","de":"Having or showing a lot of knowledge from reading and study","dt":"Okuma ve çalışma yoluyla elde edilen büyük bir bilgiye sahip olan","e1":"An erudite scholar.","e1t":"Çok bilgili bir bilgin.","e2":"He made an erudite speech.","e2t":"Bilgece (derin bilgili) bir konuşma yaptı."},{"w":"eschew","tr":"kaçınmak / sakınmak / uzak durmak","te":"Verb","tt":"Fiil","de":"To avoid something intentionally","dt":"Bir şeyden kasten kaçınmak","e1":"He eschews publicity.","e1t":"Reklamdan (tanınmaktan) kaçınır.","e2":"To eschew violence.","e2t":"Şiddetten uzak durmak."},{"w":"esoteric","tr":"yalnız uzmanların anlayacağı / ezoterik / gizli","te":"Adjective","tt":"Sıfat","de":"Likely to be understood by only a few people with special knowledge","dt":"Sadece özel bilgisi olan az sayıda kişinin anlayabileceği","e1":"Esoteric subjects like quantum physics.","e1t":"Kuantum fiziği gibi karmaşık (herkesin anlayamayacağı) konular.","e2":"An esoteric religion.","e2t":"Ezoterik (gizli) bir din."},{"w":"espouse","tr":"benimsemek / desteklemek / savunmak","te":"Verb","tt":"Fiil","de":"To become involved with or support an activity or opinion","dt":"Bir faaliyete veya görüşe dahil olmak veya onu desteklemek","e1":"He espoused the cause of environmental protection.","e1t":"Çevre koruma davasını benimsedi.","e2":"To espouse a new theory.","e2t":"Yeni bir teoriyi savunmak."},{"w":"estrange","tr":"uzaklaştırmak / yabancılaştırmak / arasını açmak","te":"Verb","tt":"Fiil","de":"To cause someone to no longer be friendly or close to another","dt":"Birinin başkasıyla artık dost veya yakın olmamasına neden olmak","e1":"His behavior estranged him from his family.","e1t":"Davranışları onu ailesinden uzaklaştırdı.","e2":"Estranged husband/wife (living apart).","e2t":"Ayrı yaşayan (araları açık) eş."},{"w":"ethereal","tr":"hafif ve zarif / ruhani / göksel","te":"Adjective","tt":"Sıfat","de":"Very light and delicate, as if not of this world","dt":"Bu dünyaya ait değilmiş gibi çok hafif ve zarif","e1":"Her ethereal beauty.","e1t":"Onun ruhani (eşsiz) güzelliği.","e2":"Ethereal music.","e2t":"İnsanı alıp götüren (hafif ve zarif) müzik."},{"w":"ethos","tr":"toplumsal değerler / ahlak yapısı / ruh","te":"Noun","tt":"İsim","de":"The set of beliefs or ideas about social behavior and relationships","dt":"Sosyal davranış ve ilişkilere dair inançlar veya fikirler bütünü","e1":"The working","e1t":"class ethos.","e2":"İşçi sınıfı ahlakı (kültürü).","e2t":"The company's ethos of hard work."},{"w":"eulogy","tr":"övgü konuşması / methiye / cenaze konuşması","te":"Noun","tt":"İsim","de":"A speech or piece of writing that praises someone highly, especially at a funeral","dt":"Birini, özellikle cenazesinde yüksek derecede öven konuşma veya yazı","e1":"To deliver a moving eulogy.","e1t":"Duygusal bir methiye (ölüm ilanı konuşması) yapmak.","e2":"A eulogy to a lost friend.","e2t":"Kaybedilen bir dosta övgü."},{"w":"euphemism","tr":"örtmece / edebi kelam / iyi ad takma","te":"Noun","tt":"İsim","de":"A word or phrase used to avoid saying an unpleasant or offensive word","dt":"Nahoş veya kırıcı bir kelimeyi söylememek için kullanılan söz","e1":"\"To pass away\" is a euphemism for \"to die\".","e1t":"\"Vefat etmek\", \"ölmek\" kelimesi için bir örtmecedir.","e2":"To use a euphemism.","e2t":"Kibar bir ifade (örtmece) kullanmak."},{"w":"evanescent","tr":"kısa ömürlü / geçici / kaybolan","te":"Adjective","tt":"Sıfat","de":"Lasting for only a very short time (formal)","dt":"Sadece çok kısa bir süre süren (resmi)","e1":"The evanescent nature of youth.","e1t":"Gençliğin gelip geçici doğası.","e2":"Evanescent fame.","e2t":"Kısa süren şöhret."},{"w":"evasive","tr":"kaçamaklı / kaçınan / üstü kapalı","te":"Adjective","tt":"Sıfat","de":"Done to avoid something or not giving a direct answer","dt":"Bir şeyden kaçınmak için yapılan veya net cevap vermeyen","e1":"He gave an evasive answer.","e1t":"Kaçamak bir cevap verdi.","e2":"To take evasive action (to avoid an accident).","e2t":"Kaçınma manevrası (hareketi) yapmak."},{"w":"evenhanded","tr":"adil / tarafsız / hakkaniyetli","te":"Adjective","tt":"Sıfat","de":"Completely fair, especially when dealing with different groups","dt":"Özellikle farklı gruplarla ilgilenirken tamamen adil olan","e1":"An evenhanded approach to the problem.","e1t":"Soruna adil (tarafsız) bir yaklaşım.","e2":"Evenhanded treatment.","e2t":"Hakkaniyetli muamele."},{"w":"exacerbate","tr":"kötüleştirmek / şiddetlendirmek / azdırmak","te":"Verb","tt":"Fiil","de":"To make something that is already bad even worse","dt":"Zaten kötü olan bir şeyi daha da kötü hale getirmek","e1":"His comments only exacerbated the situation.","e1t":"Onun yorumları durumu sadece daha da kötüleştirdi.","e2":"To exacerbate a problem.","e2t":"Bir sorunu şiddetlendirmek."},{"w":"exacting","tr":"titiz / zorlu / özen isteyen","te":"Adjective","tt":"Sıfat","de":"Needing a lot of care, effort, and attention to detail","dt":"Çok fazla özen, çaba ve detaylara dikkat gerektiren","e1":"She has very exacting standards.","e1t":"Çok yüksek (titiz) standartları var.","e2":"An exacting job.","e2t":"Zorlu (özen isteyen) bir iş."},{"w":"exasperate","tr":"çileden çıkarmak / bıktırmak / çok kızdırmak","te":"Verb","tt":"Fiil","de":"To annoy someone very much","dt":"Birini çok fazla sinirlendirmek","e1":"His constant complaining exasperates me.","e1t":"Sürekli şikayet etmesi beni çileden çıkarıyor.","e2":"To feel exasperated.","e2t":"Bıkmış (kızgın) hissetmek."},{"w":"excise","tr":"çıkarmak / kesip atmak / tüketim vergisi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To remove something by cutting it; or a tax on certain goods","dt":"Bir şeyi keserek çıkarmak; veya belirli mallar üzerindeki vergi","e1":"To excise a tumor.","e1t":"Bir tümörü (ameliyatla) çıkarmak.","e2":"The scenes were excised from the film.","e2t":"Sahneler filmden çıkarıldı."},{"w":"excoriate","tr":"sert eleştirmek / derisini yüzmek / yermek","te":"Verb","tt":"Fiil","de":"To criticize someone very harshly","dt":"Birini çok sert bir şekilde eleştirmek","e1":"The report excoriates the government for its failure.","e1t":"Rapor, başarısızlığından dolayı hükümeti yerden yere vuruyor.","e2":"To excoriate the skin (medical).","e2t":"Deriyi tahriş etmek (yüzmek)."},{"w":"excruciating","tr":"dayanılmaz / ızdırap verici / çok şiddetli","te":"Adjective","tt":"Sıfat","de":"Extremely painful or unpleasant","dt":"Son derece acı verici veya nahoş","e1":"Excruciating pain.","e1t":"Dayanılmaz acı.","e2":"An excruciating silence.","e2t":"(Sıkıntı verici) çok rahatsız edici bir sessizlik."},{"w":"execrate","tr":"lanet etmek / tiksinmek / nefret etmek","te":"Verb","tt":"Fiil","de":"To express or feel extreme loathing for (formal)","dt":"Aşırı nefret veya iğrenme hissetmek/ifade etmek (resmi)","e1":"They execrate the memory of the dictator.","e1t":"Diktatörün hatırasına lanet ediyorlar.","e2":"To execrate violence.","e2t":"Şiddetten nefret etmek."},{"w":"exempt","tr":"muaf / muaf tutmak","te":"Adjective/Verb","tt":"With special permission not to do something","de":"Bir şeyi yapmama konusunda özel izinli (muaf)","dt":"Small businesses are exempt from this tax.","e1":"Küçük işletmeler bu vergiden muaftır.","e1t":"To exempt someone from military service.","e2":"Birini askerlikten muaf tutmak.","e2t":""},{"w":"exertion","tr":"çaba / gayret / uğraş","te":"Noun","tt":"İsim","de":"Use of physical or mental effort","dt":"Fiziksel veya zihinsel çaba kullanımı","e1":"Physical exertion.","e1t":"Fiziksel çaba (efor).","e2":"He fainted from over","e2t":"exertion."},{"w":"exhilarate","tr":"coşturmak / neşelendirmek / canlandırmak","te":"Verb","tt":"Fiil","de":"To make someone feel very excited and happy","dt":"Birini çok heyecanlı ve mutlu hissettirmek","e1":"The mountain air exhilarated us.","e1t":"Dağ havası bizi canlandırdı (coşturdu).","e2":"Exhilarating experience.","e2t":"Heyecan verici (canlandırıcı) deneyim."},{"w":"exhort","tr":"teşvik etmek / öğütlemek / ısrarla tavsiye etmek","te":"Verb","tt":"Fiil","de":"To strongly encourage someone to do something","dt":"Birini bir şey yapması için güçlü bir şekilde teşvik etmek","e1":"He exhorted his followers to remain calm.","e1t":"Takipçilerini sakin kalmaya çağırdı (teşvik etti).","e2":"To exhort someone to action.","e2t":"Birini harekete geçmeye teşvik etmek."},{"w":"exhume","tr":"mezardan çıkarmak / gün ışığına çıkarmak","te":"Verb","tt":"Fiil","de":"To remove a dead body from the ground","dt":"Bir cesedi topraktan (mezardan) çıkarmak","e1":"The body was exhumed for an autopsy.","e1t":"Ceset otopsi için mezardan çıkarıldı.","e2":"To exhume a secret.","e2t":"Bir sırrı gün ışığına çıkarmak."},{"w":"exigent","tr":"acil / titiz / çok şey bekleyen","te":"Adjective","tt":"Sıfat","de":"Needing immediate attention; or demanding","dt":"Acil dikkat gerektiren; veya talepkar","e1":"An exigent problem.","e1t":"Acil (ivedi) bir sorun.","e2":"Exigent circumstances.","e2t":"Olağanüstü (acil) durumlar."},{"w":"exodus","tr":"kitlesel göç / toplu çıkış","te":"Noun","tt":"İsim","de":"A situation in which many people leave a place at the same time","dt":"Birçok insanın aynı anda bir yeri terk etmesi durumu","e1":"A mass exodus of refugees.","e1t":"Mültecilerin kitlesel göçü.","e2":"The exodus from the cities to the countryside.","e2t":"Şehirlerden kırsala göç."},{"w":"exorbitant","tr":"aşırı / fahiş (fiyat vb.)","te":"Adjective","tt":"Sıfat","de":"(Of prices or demands) much too high","dt":"(Fiyat veya talepler için) çok yüksek","e1":"Exorbitant prices.","e1t":"Fahiş (çok yüksek) fiyatlar.","e2":"Exorbitant rent.","e2t":"Aşırı yüksek kira."},{"w":"exotic","tr":"egzotik / yabancı / sıra dışı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unusual and exciting because of coming from a far country","dt":"Uzak bir ülkeden geldiği için sıra dışı ve heyecan verici","e1":"Exotic fruits.","e1t":"Egzotik meyveler.","e2":"An exotic destination.","e2t":"Sıra dışı (egzotik) bir yer."},{"w":"expanse","tr":"geniş alan / genişlik / enginlik","te":"Noun","tt":"İsim","de":"A large open area of land or water","dt":"Geniş açık arazi veya su alanı","e1":"The vast expanse of the desert.","e1t":"Çölün uçsuz bucaksız enginliği.","e2":"A wide expanse of blue sky.","e2t":"Mavi gökyüzünün geniş alanı."},{"w":"expatriate","tr":"gurbetçi / sürgün / vatandaşlıktan çıkarmak","te":"Noun/Adj/Verb","tt":"A person who lives in a foreign country","de":"Yabancı bir ülkede yaşayan kişi","dt":"British expatriates living in Turkey.","e1":"Türkiye'de yaşayan İngiliz gurbetçiler (ekspatlar).","e1t":"To expatriate a criminal.","e2":"Bir suçluyu sürgün etmek (vatandaşlıktan çıkarmak).","e2t":""},{"w":"expedient","tr":"uygun / elverişli / çıkara dayalı / çare","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Helpful or useful in a particular situation, even if not moral","dt":"Ahlaki olmasa bile belirli bir durumda yararlı veya uygun olan","e1":"A political expedient.","e1t":"Siyasi bir çare (çıkara dayalı çözüm).","e2":"It was deemed expedient to say nothing.","e2t":"Hiçbir şey söylememenin uygun (elverişli) olduğuna karar verildi."},{"w":"expend","tr":"harcamak / sarf etmek / tüketmek","te":"Verb","tt":"Fiil","de":"To use up time, money, or energy","dt":"Zaman, para veya enerjiyi harcamak (tüketmek)","e1":"To expend energy on a project.","e1t":"Bir projeye enerji sarf etmek.","e2":"Governments expend a lot of money on defense.","e2t":"Hükümetler savunmaya çok para harcıyor."},{"w":"expertize / expertise","tr":"uzmanlaşmak / uzmanlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"High level of knowledge or skill","dt":"Yüksek düzeyde bilgi veya beceri","e1":"Professional expertise.","e1t":"Profesyonel uzmanlık.","e2":"To have expertise in AI.","e2t":"Yapay zeka konusunda uzmanlığa sahip olmak."},{"w":"exploitative","tr":"sömürücü / istismarcı","te":"Adjective","tt":"Sıfat","de":"Using someone unfairly for your own advantage","dt":"Kendi avantajı için birini adaletsizce kullanan","e1":"Exploitative labor practices.","e1t":"Sömürücü çalışma uygulamaları.","e2":"An exploitative relationship.","e2t":"İstismarcı bir ilişki."},{"w":"exponent","tr":"savunucu / temsilci / üs (matematik)","te":"Noun","tt":"İsim","de":"A person who supports an idea; or a mathematical symbol","dt":"Bir fikri destekleyen kişi; veya matematiksel üs","e1":"A leading exponent of modern art.","e1t":"Modern sanatın önde gelen temsilcisi.","e2":"Exponential growth.","e2t":"Üssel (katlanarak) büyüme."},{"w":"exposition","tr":"sergi / açıklama / giriş (müzik)","te":"Noun","tt":"İsim","de":"A large public event showing art or products; or a clear explanation","dt":"Sanat veya ürünlerin gösterildiği büyük etkinlik; veya net bir açıklama","e1":"The World Exposition (Expo).","e1t":"Dünya Sergisi (Expo).","e2":"A clear exposition of his views.","e2t":"Görüşlerinin net bir açıklaması."},{"w":"expound","tr":"açıklamak / yorumlamak / dile getirmek","te":"Verb","tt":"Fiil","de":"To explain an idea or theory in detail","dt":"Bir fikri veya teoriyi detaylıca açıklamak","e1":"He expounded his theories on education.","e1t":"Eğitim hakkındaki teorilerini açıkladı.","e2":"To expound a text.","e2t":"Bir metni yorumlamak."},{"w":"extant","tr":"mevcut / halen var olan","te":"Adjective","tt":"Sıfat","de":"Still existing in spite of being very old","dt":"Çok eski olmasına rağmen hala var olan","e1":"The oldest extant manuscript.","e1t":"Mevcut olan (günümüze ulaşan) en eski el yazması.","e2":"Extant species.","e2t":"Soyu tükenmemiş (mevcut) türler."},{"w":"extol","tr":"övmek / yere göğe sığdıramamak","te":"Verb","tt":"Fiil","de":"To praise highly","dt":"Yüksek derecede övmek","e1":"To extol the virtues of a healthy diet.","e1t":"Sağlıklı beslenmenin erdemlerini yere göğe sığdıramamak.","e2":"He extolled his team's performance.","e2t":"Takımının performansını övdü."},{"w":"extractive","tr":"çıkarımsal / çıkarma ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to getting resources out of the earth","dt":"Yeryüzünden kaynakları çıkarma ile ilgili","e1":"Extractive industries (mining, oil).","e1t":"Madencilik (kaynak çıkarma) endüstrileri.","e2":"Extractive metallurgy.","e2t":"Metal çıkarma (metalürjisi)."},{"w":"extradite","tr":"iade etmek (suçlu) / geri vermek","te":"Verb","tt":"Fiil","de":"To send a person back to another country for trial","dt":"Bir kişiyi yargılanması için başka bir ülkeye geri göndermek","e1":"He was extradited to Britain from Turkey.","e1t":"Türkiye'den İngiltere'ye iade edildi.","e2":"Extradition treaty.","e2t":"Suçluların iadesi anlaşması."},{"w":"extraneous","tr":"ilgisiz / konu dışı / dışsal","te":"Adjective","tt":"Sıfat","de":"Not directly connected or related to a matter","dt":"Bir konuyla doğrudan bağlantılı veya ilgili olmayan","e1":"Extraneous information.","e1t":"Gereksiz (konu dışı) bilgi.","e2":"Extraneous factors.","e2t":"Dışsal (ilgisiz) faktörler."},{"w":"exuberant","tr":"coşkulu / hayat dolu / gür (bitki)","te":"Adjective","tt":"Sıfat","de":"Very energetic and happy; or growing thickly","dt":"Çok enerjik ve mutlu; veya gür büyüyen","e1":"An exuberant personality.","e1t":"Hayat dolu (coşkulu) bir kişilik.","e2":"Exuberant vegetation.","e2t":"Gür bitki örtüsü."},{"w":"exude","tr":"yaymak / sızdırmak / belli etmek","te":"Verb","tt":"Fiil","de":"To produce a liquid or smell; or to show a feeling strongly","dt":"Bir sıvı veya koku çıkarmak; veya bir duyguyu güçlü şekilde göstermek","e1":"To exude confidence.","e1t":"Özgüven yaymak (belli etmek).","e2":"Pine trees exude resin.","e2t":"Çam ağaçları reçine sızdırır."},{"w":"facade / façade","tr":"dış görünüş / binanın ön yüzü / maske","te":"Noun","tt":"İsim","de":"The front of a building; or a false appearance","dt":"Bir binanın ön yüzü; veya yanıltıcı dış görünüş","e1":"A classical facade.","e1t":"Klasik bir bina cephesi.","e2":"Behind a facade of friendship.","e2t":"Dostluk maskesi (görüntüsü) arkasında."},{"w":"facetious","tr":"şakacı / yerli yersiz şaka yapan","te":"Adjective","tt":"Sıfat","de":"Trying to be funny at a time when it is not appropriate","dt":"Uygun olmayan bir zamanda komik olmaya çalışan","e1":"A facetious remark.","e1t":"Yerli yersiz (şakacı) bir söz.","e2":"Don't be so facetious.","e2t":"Bu kadar cıvık (şakacı) olma."},{"w":"facile","tr":"kolay / yüzeysel / zahmetsiz","te":"Adjective","tt":"Sıfat","de":"(Of success) easily achieved; or (of ideas) too simple","dt":"(Başarı için) kolayca elde edilen; veya (fikir için) çok basit/yüzeysel","e1":"A facile victory.","e1t":"Kolay bir zafer.","e2":"A facile explanation.","e2t":"Yüzeysel (basit) bir açıklama."},{"w":"fallible","tr":"yanılabilir / hata yapabilir","te":"Adjective","tt":"Sıfat","de":"Able to make mistakes or be wrong","dt":"Hata yapabilen veya yanılabilen","e1":"Humans are fallible.","e1t":"İnsanlar yanılabilir (beşer şaşar).","e2":"A fallible memory.","e2t":"Yanılabilir bir hafıza."},{"w":"fallout","tr":"nükleer artık / sonuç / yan etki","te":"Noun","tt":"İsim","de":"Radioactive dust after a nuclear explosion; or bad results","dt":"Nükleer patlama sonrası radyoaktif toz; veya kötü sonuçlar","e1":"Radioactive fallout.","e1t":"Radyoaktif serpinti.","e2":"The political fallout from the scandal.","e2t":"Skandalın siyasi sonuçları (artçı etkileri)."},{"w":"falter","tr":"tereddüt etmek / sendelemek / aksamak","te":"Verb","tt":"Fiil","de":"To lose strength or purpose and stop moving as well","dt":"Gücünü veya amacını yitirmek ve yavaşlamak (aksamak)","e1":"His voice faltered.","e1t":"Sesi titredi (duraksadı).","e2":"The economy is starting to falter.","e2t":"Ekonomi aksamaya (teklemeğe) başlıyor."},{"w":"fanatic","tr":"fanatik / bağnaz / aşırı düşkün","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person with extremely strong beliefs; or a very enthusiastic supporter","dt":"Çok güçlü inançları olan kişi; veya çok hevesli destekçi","e1":"A religious fanatic.","e1t":"Dini fanatik.","e2":"A fitness fanatic.","e2t":"Spor delisi (düşkünü)."},{"w":"farcical","tr":"saçma / gülünç / farsa dayalı","te":"Adjective","tt":"Sıfat","de":"Ridiculous or completely disorganized","dt":"Gülünç veya tamamen düzensiz","e1":"The whole situation was farcical.","e1t":"Tüm durum saçmaydı (komediydi).","e2":"A farcical trial.","e2t":"Gülünç (saçma) bir duruşma."},{"w":"fastidious","tr":"titiz / çok seçici / zor beğenen","te":"Adjective","tt":"Sıfat","de":"Very careful about small details; or wanting everything clean","dt":"Küçük detaylar konusunda çok dikkatli; veya her şeyin temiz olmasını isteyen","e1":"He is very fastidious about his food.","e1t":"Yemekleri konusunda çok titizdir.","e2":"Fastidious attention to detail.","e2t":"Detaylara gösterilen titiz dikkat."},{"w":"fathom","tr":"anlamak / kavramak / kulaç (ölçü birimi)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To understand someone or something after much thought","dt":"Üzerinde çok düşündükten sonra birini veya bir şeyi anlamak","e1":"I can't fathom why she left.","e1t":"Neden gittiğini bir türlü anlayamıyorum.","e2":"To fathom a mystery.","e2t":"Bir gizemi çözmek."},{"w":"fatuous","tr":"aptalca / boş / anlamsız","te":"Adjective","tt":"Sıfat","de":"Stupid, not correct, or not carefully thought about","dt":"Aptalca, yanlış veya üzerinde dikkatlice düşünülmemiş","e1":"A fatuous remark.","e1t":"Aptalca (yersiz) bir söz.","e2":"A fatuous smile.","e2t":"Anlamsız (boş) bir gülümseme."},{"w":"feckless","tr":"beceriksiz / sorumsuz / zayıf karakterli","te":"Adjective","tt":"Sıfat","de":"Weak in character and lacking determination","dt":"Zayıf karakterli ve azimden yoksun","e1":"A feckless young man.","e1t":"Sorumsuz (hayta) genç bir adam.","e2":"Feckless policies.","e2t":"Etkisiz (beceriksiz) politikalar."},{"w":"felicity","tr":"mutluluk / saadet / yerindelik (ifade)","te":"Noun","tt":"İsim","de":"Happiness; or the quality of being well chosen","dt":"Mutluluk; veya (ifade için) çok yerinde olma niteliği","e1":"Domestic felicity.","e1t":"Aile saadeti.","e2":"He writes with great felicity.","e2t":"Çok yerinde (zarif) bir dille yazıyor."},{"w":"fervor / fervour","tr":"coşku / heyecan / ateşlilik","te":"Noun","tt":"İsim","de":"Strong and sincere beliefs or feelings","dt":"Güçlü ve samimi inançlar veya duygular","e1":"Religious fervor.","e1t":"Dini coşku.","e2":"Patriotic fervor.","e2t":"Vatanseverlik heyecanı."},{"w":"fester","tr":"iltihaplanmak / (kötü durum) giderek kötüleşmek","te":"Verb","tt":"Fiil","de":"(Of a cut) to become infected; or to become worse because of neglect","dt":"(Yara için) iltihaplanmak; veya ihmal nedeniyle (sorun için) kötüleşmek","e1":"The wound began to fester.","e1t":"Yara iltihaplanmaya başladı.","e2":"Don't let your resentment fester.","e2t":"Dargınlığının içine dert olmasına (büyümesine) izin verme."},{"w":"festive","tr":"şenlikli / bayram havasında / neşeli","te":"Adjective","tt":"Sıfat","de":"Happy and enjoyable because of a festival or holiday","dt":"Bir festival veya bayram nedeniyle mutlu ve keyifli","e1":"A festive mood.","e1t":"Şenlikli bir ruh hali.","e2":"The festive season.","e2t":"Bayram (tatil) dönemi."},{"w":"fetid / foetid","tr":"kötü kokulu / kokuşmuş / pis","te":"Adjective","tt":"Sıfat","de":"Smelling extremely unpleasant","dt":"Son derece nahoş kokan","e1":"The fetid air of the swamp.","e1t":"Bataklığın o kokuşmuş havası.","e2":"A fetid odor.","e2t":"Pis bir koku."},{"w":"fiasco","tr":"büyük başarısızlık / fiyasko","te":"Noun","tt":"İsim","de":"Something that is a complete failure, especially in an embarrassing way","dt":"Özellikle utanç verici bir şekilde tam bir başarısızlık olan şey","e1":"The party was a complete fiasco.","e1t":"Parti tam bir fiyaskoydu.","e2":"Financial fiasco.","e2t":"Finansal çöküş."},{"w":"fickle","tr":"kararsız / maymun iştahlı / değişken","te":"Adjective","tt":"Sıfat","de":"Changing your mind or feelings often and quickly","dt":"Fikirlerini veya duygularını sık sık ve hızla değiştiren","e1":"Fickle weather.","e1t":"Değişken hava.","e2":"The fickle nature of fame.","e2t":"Şöhretin değişken (vefasız) doğası."},{"w":"fidelity","tr":"sadakat / bağlılık / doğruluk (ses/görüntü)","te":"Noun","tt":"İsim","de":"Loyalty to a person or belief; or the degree of accuracy","dt":"Bir kişiye veya inanca sadakat; veya doğruluk derecesi","e1":"Marital fidelity.","e1t":"Evlilik sadakati.","e2":"High fidelity (Hi","e2t":"Fi)."},{"w":"figurative","tr":"mecazi / temsili / figüratif (sanat)","te":"Adjective","tt":"Sıfat","de":"Using words in a way that is different from the basic meaning","dt":"Kelimeleri temel anlamından farklı bir şekilde kullanma (mecazi)","e1":"Figurative language.","e1t":"Mecazi dil.","e2":"Figurative art (showing people/objects).","e2t":"Figüratif sanat."},{"w":"filament","tr":"ince lif / tel / filaman","te":"Noun","tt":"İsim","de":"A thin thread or wire, especially inside a light bulb","dt":"İnce ip veya tel, özellikle ampul içindeki tel","e1":"The filament in the lamp has broken.","e1t":"Lambanın teli (filamanı) kopmuş.","e2":"Glass filaments.","e2t":"Cam lifleri."},{"w":"filial","tr":"evlada ait / evlatla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the relationship of a son or daughter to their parents","dt":"Bir oğul veya kızın ebeveynleriyle olan ilişkisiyle ilgili","e1":"Filial duty.","e1t":"Evlatlık görevi.","e2":"Filial affection.","e2t":"Evlat sevgisi."},{"w":"finicky","tr":"titiz / seçici / müşkülpesent","te":"Adjective","tt":"Sıfat","de":"Difficult to please and giving too much attention to small details","dt":"Memnun etmesi zor ve küçük detaylara aşırı dikkat eden","e1":"A finicky eater.","e1t":"Yemek seçen (zor beğenen) biri.","e2":"He is very finicky about his clothes.","e2t":"Kıyafetleri konusunda çok titizdir."},{"w":"fissure","tr":"yarık / çatlak / ayrılık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A deep crack in rock or earth; or a split in a group","dt":"Kaya veya topraktaki derin çatlak; veya bir gruptaki bölünme","e1":"A fissure in the earth's surface.","e1t":"Yer yüzeyindeki bir yarık.","e2":"Fissures within the political party.","e2t":"Siyasi parti içindeki derin çatlaklar (ayrılıklar)."},{"w":"flagrant","tr":"bariz kötü / apaçık / hayâsızca","te":"Adjective","tt":"Sıfat","de":"(Of something bad) shocking because it is done in a very obvious way","dt":"(Kötü bir şey için) çok açık yapıldığı için şoke edici olan","e1":"A flagrant violation of human rights.","e1t":"İnsan haklarının bariz (apaçık) bir ihlali.","e2":"A flagrant lie.","e2t":"Utanmazca (apaçık) bir yalan."},{"w":"flamboyant","tr":"gösterişli / frapan / cafcaflı","te":"Adjective","tt":"Sıfat","de":"Intended to be noticed, especially by being brightly colored","dt":"Özellikle parlak renkli olduğu için fark edilmeyi amaçlayan","e1":"A flamboyant lifestyle.","e1t":"Gösterişli bir yaşam tarzı.","e2":"Flamboyant clothes.","e2t":"Frapan (dikkat çekici) kıyafetler."},{"w":"flaunt","tr":"gösteriş yapmak / hava atmak / sergilemek","te":"Verb","tt":"Fiil","de":"To show something you are proud of so that other people will admire it","dt":"Başkaları hayran kalsın diye gurur duyulan bir şeyi sergilemek","e1":"To flaunt your wealth.","e1t":"Servetini sergilemek (hava atmak).","e2":"She likes to flaunt her success.","e2t":"Başarısıyla gösteriş yapmayı sever."},{"w":"fledgling","tr":"acemi / yeni başlayan / kuş yavrusu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person or organization that is immature or inexperienced","dt":"Deneyimsiz kişi veya organizasyon","e1":"A fledgling democracy.","e1t":"Yeni filizlenen (henüz olgunlaşmamış) demokrasi.","e2":"Fledgling company.","e2t":"Yeni kurulan (yolun başındaki) şirket."},{"w":"fleeting","tr":"geçici / kısa süren / anlık","te":"Adjective","tt":"Sıfat","de":"Short or quick","dt":"Kısa veya hızlı","e1":"A fleeting glimpse.","e1t":"Anlık (şöyle bir) bakış.","e2":"For a fleeting moment.","e2t":"Kısa bir an için."},{"w":"flinch","tr":"geri çekilmek / irkilmek / kaçınmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make a sudden movement because of fear or pain","dt":"Korku veya acı nedeniyle ani bir hareketle geri çekilmek","e1":"He didn't even flinch when the needle went in.","e1t":"İğne girerken irkilmedi (kılı bile kıpırdamadı) bile.","e2":"To flinch from a duty.","e2t":"Bir görevden kaçınmak."},{"w":"flippant","tr":"düşüncesizce / ciddiyetsiz / saygısızca (şaka yollu)","te":"Adjective","tt":"Sıfat","de":"Not serious about a serious subject in an attempt to be funny","dt":"Komik olmaya çalışırken ciddi bir konuyu hafife alan","e1":"A flippant remark.","e1t":"Ciddiyetsiz (saygısızca) bir söz.","e2":"Don't be so flippant about your exam.","e2t":"Sınavın hakkında bu kadar lakayıt (ciddiyetsiz) olma."},{"w":"florid","tr":"süslü / kırmızı yüzlü / ağdalı","te":"Adjective","tt":"Sıfat","de":"With too much decoration; or having a red face","dt":"Çok fazla süslemeli; veya (yüz için) kırmızı/pembe","e1":"Florid prose (writing).","e1t":"Ağdalı (çok süslü) nesir.","e2":"A florid complexion.","e2t":"Kırmızımsı bir yüz rengi."},{"w":"flounder","tr":"bocalamak / çabalamak / pisi balığı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To experience great difficulties or be helpless","dt":"Büyük zorluklar yaşamak veya çaresiz kalmak","e1":"The company is floundering in the current economic crisis.","e1t":"Şirket mevcut ekonomik krizde bocalamaktadır.","e2":"To flounder in the mud.","e2t":"Çamurda debelenmek (çabalamak)."},{"w":"fluke","tr":"tesadüfi başarı / şans eseri olan şey","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something good that happens because of luck","dt":"Şans eseri gerçekleşen iyi şey","e1":"His victory was a complete fluke.","e1t":"Zaferi tamamen bir şanstı (tesadüftü).","e2":"By a lucky fluke.","e2t":"Şans eseri."},{"w":"flux","tr":"akış / sürekli değişim / lehim yardımcısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Continuous change; or the rate of flow of energy","dt":"Sürekli değişim; veya enerji akış hızı","e1":"Everything is in a state of flux.","e1t":"Her şey sürekli bir değişim (akış) içinde.","e2":"Magnetic flux (physics).","e2t":"Manyetik akı."},{"w":"fodder","tr":"hayvan yemi / malzeme (olumsuz anlamda)","te":"Noun/Verb","tt":"İsim/Fiil","de":"Food for horses or cows; or people considered as useful for one purpose only","dt":"At veya inekler için yiyecek; veya sadece bir amaç için (harcanabilir) görülen şeyler","e1":"Cannon fodder (soldiers).","e1t":"Top yemi (asker).","e2":"Tabloid fodder (celebrities).","e2t":"Magazin malzemesi."},{"w":"folly","tr":"aptallık / budalalık / anlamsız yapı","te":"Noun","tt":"İsim","de":"A lack of good judgment; or a stupid action","dt":"Sağduyu eksikliği; veya aptalca bir eylem","e1":"The folly of war.","e1t":"Savaşın budalalığı.","e2":"It would be pure folly to quit now.","e2t":"Şimdi bırakmak tam bir aptallık olurdu."},{"w":"foment","tr":"kışkırtmak / körüklemek / pansuman yapmak","te":"Verb","tt":"Fiil","de":"To cause trouble or violence to develop","dt":"Sorun veya şiddetin gelişmesine neden olmak (kışkırtmak)","e1":"To foment revolution.","e1t":"Devrim kışkırtmak (körüklemek).","e2":"To foment trouble.","e2t":"Sorun çıkarmak."},{"w":"fondness","tr":"sevgi / düşkünlük / sempati","te":"Noun","tt":"İsim","de":"A feeling of affection for someone or something","dt":"Birine veya bir şeye karşı duyulan sevgi/ilgi","e1":"A fondness for chocolate.","e1t":"Çikolataya karşı bir düşkünlük.","e2":"He remembered her with great fondness.","e2t":"Onu büyük bir sevgiyle hatırladı."},{"w":"forensic","tr":"adli / kriminalistik","te":"Adjective","tt":"Sıfat","de":"Relating to using scientific methods to solve crimes","dt":"Suçları çözmek için bilimsel yöntemlerin kullanılmasıyla ilgili","e1":"Forensic evidence.","e1t":"Adli kanıt.","e2":"Forensic medicine.","e2t":"Adli tıp."},{"w":"foreseeable","tr":"öngörülebilir / tahmin edilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be predicted","dt":"Tahmin edilebilen","e1":"In the foreseeable future.","e1t":"Öngörülebilir gelecekte.","e2":"Foreseeable risks.","e2t":"Tahmin edilebilir riskler."},{"w":"forfeit","tr":"hakkı kaybetmek / ceza olarak vermek / vazgeçmek","te":"Verb/Noun/Adj","tt":"To lose a right or possession as a punishment","de":"Ceza olarak bir hakkı veya mülkü kaybetmek","dt":"To forfeit your deposit.","e1":"Depozitoyu yakmak (kaybetmek).","e1t":"He has forfeited his right to a trial.","e2":"Yargılanma hakkından vazgeçti (hakkını kaybetti).","e2t":""},{"w":"forlorn","tr":"terk edilmiş / umutsuz / perişan","te":"Adjective","tt":"Sıfat","de":"Alone and unhappy; or unlikely to succeed","dt":"Yalnız ve mutsuz; veya başarılı olması muhtemel olmayan","e1":"A forlorn figure standing in the rain.","e1t":"Yağmurda duran perişan bir figür.","e2":"A forlorn hope.","e2t":"Zayıf (umutsuz) bir umut."},{"w":"forsake","tr":"terketmek / bırakmak / vazgeçmek","te":"Verb","tt":"Fiil","de":"To leave someone for ever, especially when they need you","dt":"Birini (özellikle ihtiyacı varken) sonsuza dek bırakmak","e1":"He decided to forsake his career for his family.","e1t":"Ailesi için kariyerinden vazgeçmeye karar verdi.","e2":"I will never forsake you.","e2t":"Seni asla terk etmeyeceğim."},{"w":"forthright","tr":"açık sözlü / dürüst / dosdoğru","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Saying what you think honestly and clearly","dt":"Düşündüğünü dürüstçe ve netçe söyleyen","e1":"A forthright manner.","e1t":"Açık sözlü bir tavır.","e2":"He was very forthright about his views.","e2t":"Görüşleri konusunda çok net ve dürüsttü."},{"w":"fortitude","tr":"cesaret / metanet / dayanıklılık","te":"Noun","tt":"İsim","de":"Bravery when you are facing a difficult situation","dt":"Zor bir durumla karşı karşıyayken gösterilen cesaret/metanet","e1":"Mental fortitude.","e1t":"Zihinsel metanet.","e2":"To face adversity with fortitude.","e2t":"Sıkıntılara metanetle göğüs germek."},{"w":"fractious","tr":"huysuz / kavgacı / hırçın","te":"Adjective","tt":"Sıfat","de":"Easily upset or annoyed, and often complaining","dt":"Kolayca sinirlenen ve sık sık şikayet eden","e1":"A fractious child.","e1t":"Huysuz bir çocuk.","e2":"The fractious political climate.","e2t":"Kavgacı (gergin) siyasi iklim."},{"w":"fragmentary","tr":"parçalı / bölük pörçük / eksik","te":"Adjective","tt":"Sıfat","de":"Existing only in small parts; not complete","dt":"Sadece küçük parçalar halinde var olan; tam olmayan","e1":"Fragmentary evidence.","e1t":"Bölük pörçük (eksik) kanıtlar.","e2":"Our knowledge of the event is fragmentary.","e2t":"Olay hakkındaki bilgimiz eksiktir."},{"w":"fragrant","tr":"hoş kokulu / mis kokulu","te":"Adjective","tt":"Sıfat","de":"Having a pleasant smell","dt":"Hoş bir kokusu olan","e1":"Fragrant flowers.","e1t":"Hoş kokulu çiçekler.","e2":"The air was fragrant with the smell of roses.","e2t":"Hava gül kokularıyla mis gibiydi."},{"w":"frail","tr":"zayıf / çelimsiz / kırılgan","te":"Adjective","tt":"Sıfat","de":"Weak or unhealthy, or easily damaged","dt":"Güçsüz veya sağlıksız, veya kolayca hasar görebilen","e1":"A frail old lady.","e1t":"Çelimsiz (zayıf) yaşlı bir kadın.","e2":"In a frail state of health.","e2t":"Zayıf bir sağlık durumunda."},{"w":"frantic","tr":"çılgın / panik içinde / telaşlı","te":"Adjective","tt":"Sıfat","de":"Done in a very hurried way because of fear or worry","dt":"Korku veya endişe nedeniyle çok aceleyle yapılan","e1":"Frantic efforts to find the missing child.","e1t":"Kayıp çocuğu bulmak için gösterilen panik dolu (çılgınca) çabalar.","e2":"She was frantic with worry.","e2t":"Endişeden ne yapacağını şaşırmış (çılgına dönmüş) haldeydi."},{"w":"fraught","tr":"dolu / yüklü / sıkıntılı","te":"Adjective","tt":"Sıfat","de":"Full of unpleasant things such as problems or dangers","dt":"Sorun veya tehlike gibi nahoş şeylerle dolu","e1":"A situation fraught with danger.","e1t":"Tehlike dolu bir durum.","e2":"The atmosphere was fraught with tension.","e2t":"Atmosfer gerilim yüklüydü."},{"w":"fray","tr":"yıpratmak / aşınmak / kavga / arbede","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of cloth) to become untidy at the edge; or a fight","dt":"(Kumaş için) kenarlarından sökülmek; veya kavga","e1":"My nerves are beginning to fray.","e1t":"Sinirlerim bozulmaya (yıpranmaya) başladı.","e2":"To enter the fray (to join a fight/argument).","e2t":"Arbedeye (kavgaya) dahil olmak."},{"w":"frenetic","tr":"çılgınca hareketli / telaşlı / hummalı","te":"Adjective","tt":"Sıfat","de":"Involving a lot of excited movement or activity","dt":"Çok fazla heyecanlı hareket veya faaliyet içeren","e1":"The frenetic pace of modern life.","e1t":"Modern hayatın hummalı (çılgın) hızı.","e2":"Frenetic activity.","e2t":"Telaşlı faaliyet."},{"w":"fret","tr":"üzülmek / endişelenmek / perde (gitar vb.)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be nervous or worried","dt":"Gergin veya endişeli olmak","e1":"Don't fret about it.","e1t":"Bunun için dertlenme (üzülme).","e2":"To fret over small details.","e2t":"Küçük detaylar üzerinde kafa yormak (endişelenmek)."},{"w":"frugal","tr":"tutumlu / idareli / sade (yemek vb.)","te":"Adjective","tt":"Sıfat","de":"Careful when using money or food; or simple","dt":"Para veya yemek kullanırken dikkatli; veya sade","e1":"A frugal lifestyle.","e1t":"Tutumlu bir yaşam tarzı.","e2":"A frugal meal of bread and cheese.","e2t":"Ekmek ve peynirden oluşan sade bir öğün."},{"w":"fruition","tr":"gerçekleşme / meyvesini verme / sonuç","te":"Noun","tt":"İsim","de":"The point at which a plan or project is successfully completed","dt":"Bir plan veya projenin başarıyla tamamlandığı an","e1":"His plans finally came to fruition.","e1t":"Planları sonunda meyvesini verdi (gerçekleşti).","e2":"To bring a project to fruition.","e2t":"Bir projeyi başarıyla sonuçlandırmak."},{"w":"fulcrum","tr":"dayanak / destek noktası / kilit nokta","te":"Noun","tt":"İsim","de":"The point on which a lever balances; or a central part","dt":"Kaldıraçın dengelendiği nokta; veya merkezi (kilit) parça","e1":"The fulcrum of the debate.","e1t":"Tartışmanın kilit noktası (dayanağı).","e2":"To act as a fulcrum.","e2t":"Dayanak noktası görevi görmek."},{"w":"fulminate","tr":"patlamak / öfkeyle eleştirmek / şiddetle karşı çıkmak","te":"Verb","tt":"Fiil","de":"To criticize someone or something very strongly","dt":"Birini veya bir şeyi çok sert bir şekilde eleştirmek","e1":"To fulminate against the government's policy.","e1t":"Hükümetin politikasına karşı ateş püskürmek (şiddetle eleştirmek).","e2":"Fulminating infection (medical","e2t":"sudden and severe)."},{"w":"fulsome","tr":"aşırı övücü / yapmacık / abartılı","te":"Adjective","tt":"Sıfat","de":"Expressing a lot of admiration in a way that does not sound sincere","dt":"Samimi gelmeyecek kadar çok hayranlık/övgü ifade eden","e1":"Fulsome praise.","e1t":"Aşırı (ve yapmacık) övgü.","e2":"Her apologies were rather fulsome.","e2t":"Özürleri oldukça abartılıydı."},{"w":"fumigate","tr":"ilaçlamak / dumanla dezenfekte etmek","te":"Verb","tt":"Fiil","de":"To use chemicals in the form of smoke to kill insects","dt":"Böcekleri öldürmek için duman şeklinde kimyasallar kullanmak","e1":"We had to fumigate the whole house for termites.","e1t":"Termitler için tüm evi ilaçlamak zorunda kaldık.","e2":"To fumigate a room.","e2t":"Bir odayı dumanla dezenfekte etmek."},{"w":"functional","tr":"işlevsel / fonksiyonel / pratik","te":"Adjective","tt":"Sıfat","de":"Designed to be practical rather than attractive","dt":"Çekici olmaktan ziyade pratik olması için tasarlanmış","e1":"Functional furniture.","e1t":"İşlevsel (kullanışlı) mobilya.","e2":"The system is now fully functional.","e2t":"Sistem şu an tamamen işlevseldir (çalışır durumdadır)."},{"w":"fungible","tr":"birbirinin yerine geçebilir / takas edilebilir","te":"Adjective","tt":"Sıfat","de":"(Of goods) easy to exchange for something else of the same type","dt":"(Mallar için) aynı türden başka bir şeyle kolayca değiştirilebilen","e1":"Money is a fungible asset.","e1t":"Para, takas edilebilir (birbirinin yerine geçer) bir varlıktır.","e2":"Non","e2t":"fungible tokens (NFTs)."},{"w":"furtive","tr":"gizli / kaçamak / sinsi","te":"Adjective","tt":"Sıfat","de":"Done in a quiet and secret way to avoid being noticed","dt":"Fark edilmemek için sessiz ve gizli yapılan","e1":"She cast a furtive glance at her watch.","e1t":"Saatime kaçamak (gizli) bir bakış attı.","e2":"Furtive behavior.","e2t":"Sinsi (şüpheli) davranış."},{"w":"futility","tr":"beyhudelik / boşunalık / yararsızlık","te":"Noun","tt":"İsim","de":"The fact of having no practical use or success","dt":"Pratik bir yararı veya başarısı olmama durumu","e1":"The futility of war.","e1t":"Savaşın beyhudeliği.","e2":"He realized the futility of his actions.","e2t":"Eylemlerinin boşuna olduğunu anladı."},{"w":"gainsay","tr":"inkâr etmek / karşı çıkmak / yalanlamak","te":"Verb","tt":"Fiil","de":"To deny or contradict a statement (formal)","dt":"Bir ifadeyi inkâr etmek veya aksini söylemek (resmi)","e1":"There is no gainsaying his competence.","e1t":"Onun yetkinliği inkâr edilemez.","e2":"To gainsay a claim.","e2t":"Bir iddiaya karşı çıkmak."},{"w":"gallant","tr":"yiğit / cesur / nazik (kadınlara karşı)","te":"Adjective","tt":"Sıfat","de":"Brave; or polite and kind towards women","dt":"Cesur; veya kadınlara karşı nazik ve saygılı","e1":"A gallant soldier.","e1t":"Yiğit bir asker.","e2":"That was very gallant of you.","e2t":"Çok nazikçe bir davranıştı."},{"w":"galvanize / galvanise","tr":"harekete geçirmek / canlandırmak / galvanizlemek","te":"Verb","tt":"Fiil","de":"To cause someone to take action; or to coat metal with zinc","dt":"Birini eyleme geçmeye itmek; veya metali çinko ile kaplamak","e1":"The tragedy galvanized the whole community into action.","e1t":"Trajedi tüm toplumu eyleme geçirdi (canlandırdı).","e2":"Galvanized steel.","e2t":"Galvanizli çelik."},{"w":"gamut","tr":"tam aralık / dizi / yelpaze","te":"Noun","tt":"İsim","de":"The whole range of things that can be included in something","dt":"Bir şeye dahil edilebilecek her şeyin bütünü (yelpazesi)","e1":"Her performance ran the gamut of emotions.","e1t":"Performansı tüm duygu yelpazesini (aralığını) kapsıyordu.","e2":"The full gamut of options.","e2t":"Seçeneklerin tamamı."},{"w":"gargantuan","tr":"devasa / muazzam / kocaman","te":"Adjective","tt":"Sıfat","de":"Enormously large","dt":"Çok büyük, devasa","e1":"A gargantuan appetite.","e1t":"Muazzam (doymak bilmez) bir iştah.","e2":"A gargantuan task.","e2t":"Çok büyük bir iş."},{"w":"garrulous","tr":"geveze / konuşkan / boşboğaz","te":"Adjective","tt":"Sıfat","de":"Talking a lot, especially about unimportant things","dt":"Özellikle önemsiz şeyler hakkında çok konuşan","e1":"A garrulous neighbor.","e1t":"Geveze bir komşu.","e2":"He became more garrulous after a few drinks.","e2t":"Birkaç içkiden sonra daha konuşkan oldu."},{"w":"gaudy","tr":"gösterişli / zevksiz / cafcaflı","te":"Adjective","tt":"Sıfat","de":"Unpleasantly bright in color and decorated too much","dt":"Hoş olmayan parlak renkli ve aşırı süslü (rüküş)","e1":"Gaudy jewelry.","e1t":"Cafcaflı (zevksiz) takılar.","e2":"The house was painted in gaudy colors.","e2t":"Ev rüküş (göz tırmalayan) renklere boyanmıştı."},{"w":"genial","tr":"cana yakın / dostça / hoş","te":"Adjective","tt":"Sıfat","de":"Friendly and pleasant","dt":"Dostça ve hoş","e1":"A genial host.","e1t":"Cana yakın bir ev sahibi.","e2":"The genial sunshine of spring.","e2t":"Baharın hoş (yumuşak) güneş ışığı."},{"w":"genteel","tr":"kibar / nazik / beyefendi / soylu gibi","te":"Adjective","tt":"Sıfat","de":"Typical of a high social class; very polite","dt":"Üst sınıfa özgü; çok nazik","e1":"A genteel accent.","e1t":"Kibar (soylu) bir aksan.","e2":"Genteel poverty (living poorly but with high","e2t":"class manners)."},{"w":"gentry","tr":"üst sınıf / seçkinler / küçük soylular","te":"Noun","tt":"İsim","de":"People of high social class, just below nobility","dt":"Soyluların hemen altındaki yüksek sosyal sınıf","e1":"The landed gentry.","e1t":"Toprak sahibi seçkinler.","e2":"Local gentry.","e2t":"Bölgenin ileri gelenleri."},{"w":"germane","tr":"ilgili / ilişkili / yerinde","te":"Adjective","tt":"Sıfat","de":"Connected with and important to a particular subject","dt":"Belirli bir konuyla bağlantılı ve önemli olan","e1":"Her comments were not germane to the discussion.","e1t":"Yorumları tartışmayla ilgili (alakalı) değildi.","e2":"Information germane to the case.","e2t":"Davayla ilişkili bilgi."},{"w":"ghastly","tr":"korkunç / hortlak gibi / çok kötü","te":"Adjective","tt":"Sıfat","de":"Very bad or unpleasant; looking like a ghost","dt":"Çok kötü veya nahoş; hayalet gibi (solgun)","e1":"A ghastly accident.","e1t":"Korkunç bir kaza.","e2":"He looked ghastly after the news.","e2t":"Haberi aldıktan sonra yüzü kireç gibi (korkunç) oldu."},{"w":"giddy","tr":"başı dönen / sersemlemiş / havai","te":"Adjective","tt":"Sıfat","de":"Feeling that everything is spinning; or silly and excited","dt":"Her şeyin döndüğünü hissetme; veya çocukça heyecanlı/havai","e1":"To feel giddy with excitement.","e1t":"Heyecandan başı dönmek.","e2":"A giddy young girl.","e2t":"Havai (hop hop) genç bir kız."},{"w":"gingerly","tr":"dikkatle / ihtiyatla / sakınarak","te":"Adverb","tt":"Zarf","de":"In a way that is very careful or cautious","dt":"Çok dikkatli veya tedbirli bir şekilde","e1":"He stepped gingerly onto the ice.","e1t":"Buzun üzerine ihtiyatla (sakınarak) bastı.","e2":"She gingerly picked up the broken glass.","e2t":"Kırık camı dikkatlice yerden aldı."},{"w":"glean","tr":"toplamak / süzmek / zorlukla bilgi edinmek","te":"Verb","tt":"Fiil","de":"To collect information in small amounts over time","dt":"Zamanla parça parça bilgi toplamak","e1":"We managed to glean some information from the report.","e1t":"Rapordan bazı bilgileri süzmeyi (toplamayı) başardık.","e2":"To glean wisdom from experience.","e2t":"Deneyimden bilgelik süzmek."},{"w":"glib","tr":"yüzeysel konuşan / ağzı kalabalık / lafazan","te":"Adjective","tt":"Sıfat","de":"Speaking easily but without thinking or sincerity","dt":"Kolay konuşan ancak düşüncesiz veya samimiyetsiz","e1":"A glib salesman.","e1t":"Ağzı iyi laf yapan (ama güven vermeyen) satıcı.","e2":"Glib answers.","e2t":"Yüzeysel (hazırca) cevaplar."},{"w":"gloat","tr":"böbürlenmek / kına yakmak / kötü niyetle sevinmek","te":"Verb","tt":"Fiil","de":"To feel great pleasure because of your own success or someone's failure","dt":"Kendi başarısından veya başkasının başarısızlığından kötü niyetli bir zevk duymak","e1":"Don't gloat over your victory.","e1t":"Zaferinle böbürlenme (veya yenilenle dalga geçme).","e2":"He gloated over his rival's misfortune.","e2t":"Rakibinin talihsizliğine kına yaktı (sevindi)."},{"w":"glossy","tr":"parlak / pürüzsüz / kuşe kağıtlı","te":"Adjective","tt":"Sıfat","de":"Smooth and shiny","dt":"Pürüzsüz ve parlak","e1":"Glossy hair.","e1t":"Parlak saçlar.","e2":"A glossy magazine.","e2t":"Kuşe kağıda basılı (parlak) dergi."},{"w":"glum","tr":"keyifsiz / asık suratlı / somurtkan","te":"Adjective","tt":"Sıfat","de":"Disappointed or unhappy, and quiet","dt":"Hayal kırıklığına uğramış veya mutsuz ve sessiz","e1":"You look very glum today.","e1t":"Bugün çok keyifsiz görünüyorsun.","e2":"A glum expression.","e2t":"Asık bir yüz ifadesi."},{"w":"gluttonous","tr":"açgözlü / obur","te":"Adjective","tt":"Sıfat","de":"Eating and drinking more than you need","dt":"İhtiyacından fazlasını yiyip içen","e1":"Gluttonous behavior.","e1t":"Oburca davranış.","e2":"A gluttonous eater.","e2t":"Çok obur biri."},{"w":"gnawing","tr":"kemirici / içini yiyen / bitmek bilmeyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Persistently worrying or distressing; or the act of biting","dt":"Sürekli endişe verici veya rahatsız edici; veya kemirme eylemi","e1":"A gnawing hunger.","e1t":"Kemirici (şiddetli) bir açlık.","e2":"Gnawing doubt.","e2t":"İçini kemiren şüphe."},{"w":"goalpost","tr":"kale direği","te":"Noun","tt":"İsim","de":"One of the two vertical posts that form a goal","dt":"Kaleyi oluşturan iki dikey direkten biri","e1":"The ball hit the goalpost.","e1t":"Top kale direğine çarptı.","e2":"To move the goalposts (idiom: to change the rules).","e2t":"Oyunun ortasında kuralları değiştirmek."},{"w":"gorge","tr":"tıkınmak / boğaz (coğrafya) / tıka basa yemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A deep narrow valley; or to eat until you are too full","dt":"Derin dar vadi; veya tıka basa yemek","e1":"A deep river gorge.","e1t":"Derin bir nehir boğazı.","e2":"They gorged themselves on chocolate.","e2t":"Çikolatayla kendilerinden geçtiler (tıkındılar)."},{"w":"gory","tr":"kanlı / vahşet dolu","te":"Adjective","tt":"Sıfat","de":"Involving a lot of blood or violence","dt":"Çok fazla kan veya şiddet içeren","e1":"A gory horror movie.","e1t":"Kanlı bir korku filmi.","e2":"The gory details of the crime.","e2t":"Suçun tüm vahşet dolu detayları."},{"w":"gossamer","tr":"incecik / tül gibi / örümcek ağı gibi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very light and thin material or spider's web","dt":"Çok hafif ve ince kumaş veya örümcek ağı","e1":"A gossamer dress.","e1t":"Tül gibi incecik bir elbise.","e2":"Gossamer wings of a butterfly.","e2t":"Bir kelebeğin tül gibi kanatları."},{"w":"gourmand","tr":"gurme / obur / ağzının tadını bilen","te":"Noun","tt":"İsim","de":"A person who enjoys eating a lot of good food","dt":"İyi yemek yemeyi seven (ve bazen aşırıya kaçan) kişi","e1":"He is a real gourmand.","e1t":"O tam bir yemek tutkunudur.","e2":"A gourmand's feast.","e2t":"Bir gurmenin şöleni. (Not: Gourmet'den biraz daha 'obur' anlamı taşır)."},{"w":"grandiose","tr":"görkemli / şatafatlı / abartılı","te":"Adjective","tt":"Sıfat","de":"Larger and more important than necessary (often negative)","dt":"Gereğinden fazla büyük ve önemli görünen (genellikle olumsuz)","e1":"Grandiose plans.","e1t":"Abartılı (görkemli görünen) planlar.","e2":"He has a grandiose style of speaking.","e2t":"Şatafatlı bir konuşma tarzı var."},{"w":"grapple","tr":"boğuşmak / uğraşmak / pençeleşmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fight with someone; or to try hard to solve a problem","dt":"Biriyle dövüşmek; veya bir sorunu çözmek için çok uğraşmak","e1":"To grapple with a difficult issue.","e1t":"Zor bir meseleyle boğuşmak (kafa yormak).","e2":"The two men grappled on the floor.","e2t":"İki adam yerde boğuştu."},{"w":"gratuitous","tr":"gereksiz / sebepsiz / bedava","te":"Adjective","tt":"Sıfat","de":"(Of something bad) not necessary or with no reason","dt":"(Kötü bir şey için) gereksiz veya nedensiz","e1":"Gratuitous violence in movies.","e1t":"Filmlerdeki lüzumsuz (sebepsiz) şiddet.","e2":"A gratuitous insult.","e2t":"Yersiz (durup dururken yapılan) bir hakaret."},{"w":"gregarious","tr":"sosyal / sokulgan / sürü halinde yaşayan","te":"Adjective","tt":"Sıfat","de":"Liking to be with other people; or living in groups","dt":"İnsanlarla olmayı seven; veya gruplar halinde yaşayan","e1":"She is very gregarious and outgoing.","e1t":"Çok sosyal ve dışa dönüktür.","e2":"Gregarious animals.","e2t":"Sürü halinde yaşayan (sosyal) hayvanlar."},{"w":"grieving","tr":"yaslı / kederli","te":"Adjective","tt":"Sıfat","de":"Feeling very sad because someone has died","dt":"Biri öldüğü için çok üzgün olan","e1":"Grieving relatives.","e1t":"Yaslı akrabalar.","e2":"A grieving mother.","e2t":"Kederli bir anne."},{"w":"grimace","tr":"yüzünü buruşturmak / ekşitmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make an ugly expression with your face because of pain or dislike","dt":"Acı veya hoşnutsuzluk nedeniyle yüzünü çirkinleştirmek","e1":"He grimaced in pain.","e1t":"Acıyla yüzünü buruşturdu.","e2":"To make a grimace.","e2t":"Yüzünü ekşitmek."},{"w":"gritty","tr":"cesur / azimli / kumlu / gerçekçi","te":"Adjective","tt":"Sıfat","de":"Brave and determined; or containing sand; or showing unpleasant reality","dt":"Cesur ve kararlı; veya kumlu; veya nahoş gerçeği gösteren","e1":"A gritty performance.","e1t":"Azimli (sert) bir performans.","e2":"A gritty description of city life.","e2t":"Şehir hayatının tüm çıplaklığıyla (nadir/sert) tasviri."},{"w":"grotesque","tr":"acayip / garip / çirkin / gülünç","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Strange and unpleasant, especially in a silly or slightly frightening way","dt":"Garip ve nahoş, özellikle gülünç veya korkutucu bir şekilde","e1":"Grotesque figures.","e1t":"Garip (ucube gibi) figürler.","e2":"A grotesque distortion of the truth.","e2t":"Gerçeğin gülünç (saçma) bir şekilde çarpıtılması."},{"w":"groundless","tr":"asılsız / dayanaksız / yersiz","te":"Adjective","tt":"Sıfat","de":"Without any good reason or evidence","dt":"Herhangi bir geçerli neden veya kanıtı olmayan","e1":"Groundless fears.","e1t":"Yersiz (temelsiz) korkular.","e2":"The accusations were groundless.","e2t":"Suçlamalar asılsızdı."},{"w":"grudge","tr":"kin / garez / hınç / esirgemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A strong feeling of anger toward someone that lasts a long time","dt":"Birine karşı uzun süren güçlü öfke duygusu","e1":"To hold a grudge against someone.","e1t":"Birine kin beslemek.","e2":"I don't grudge him his success (I am not jealous).","e2t":"Başarısını ondan esirgemiyorum (kıskanmıyorum)."},{"w":"grudging","tr":"isteksizce verilen / kıskanç","te":"Adjective","tt":"Sıfat","de":"Given or allowed only reluctantly or resentfully","dt":"Sadece isteksizce veya darılarak verilen","e1":"He gave a grudging apology.","e1t":"İsteksizce bir özür diledi.","e2":"Grudging respect.","e2t":"Gönülsüz saygı."},{"w":"grueling / gruelling","tr":"yorucu / meşakkatli / çok ağır","te":"Adjective","tt":"Sıfat","de":"Extremely tiring and difficult","dt":"Son derece yorucu ve zor","e1":"A grueling race.","e1t":"Çok ağır (yok edici) bir yarış.","e2":"Six months of grueling work.","e2t":"Altı aylık meşakkatli bir çalışma."},{"w":"gruesome","tr":"ürkütücü / korkunç / dehşet verici","te":"Adjective","tt":"Sıfat","de":"Very unpleasant and shocking, usually involving injury or death","dt":"Çok nahoş ve şok edici, genellikle yaralanma veya ölüm içeren","e1":"A gruesome murder.","e1t":"Korkunç bir cinayet.","e2":"Gruesome details.","e2t":"Ürkütücü detaylar."},{"w":"gruff","tr":"ters / aksi / boğuk (ses)","te":"Adjective","tt":"Sıfat","de":"(Of a person) unfriendly or impatient; or (of a voice) low and rough","dt":"(Kişi için) kaba veya sabırsız; veya (ses için) kalın ve pürüzlü","e1":"A gruff old man.","e1t":"Aksi bir yaşlı adam.","e2":"He spoke in a gruff voice.","e2t":"Boğuk/sert bir sesle konuştu."},{"w":"guile","tr":"kurnazlık / hile / düzenbazlık","te":"Noun","tt":"İsim","de":"Clever but sometimes dishonest behavior in order to deceive","dt":"Aldatmak için kullanılan zeki ama bazen dürüst olmayan davranış","e1":"To use guile to get what you want.","e1t":"İstediğini elde etmek için kurnazlık (hile) kullanmak.","e2":"A man without guile (honest).","e2t":"Hilesiz hurdasız (dürüst) bir adam."},{"w":"gusto","tr":"büyük keyif / şevk / lezzet","te":"Noun","tt":"İsim","de":"Great energy, enthusiasm, and enjoyment","dt":"Büyük enerji, heves ve keyif","e1":"To eat with great gusto.","e1t":"Büyük bir iştahla (keyifle) yemek.","e2":"To work with gusto.","e2t":"Şevkle çalışmak."},{"w":"haggard","tr":"bitkin / çökmüş / yorgun argın","te":"Adjective","tt":"Sıfat","de":"Looking ill or tired, especially with dark areas under the eyes","dt":"Hasta veya yorgun görünen, özellikle göz altları çökmüş","e1":"He looked haggard after staying up all night.","e1t":"Bütün gece uyanık kaldıktan sonra bitkin görünüyordu.","e2":"A haggard face.","e2t":"Çökmüş bir yüz."},{"w":"hallucination","tr":"halüsinasyon / sanrı","te":"Noun","tt":"İsim","de":"Seeing or hearing something that is not really there","dt":"Gerçekte olmayan bir şeyi görme veya duyma","e1":"Visual hallucinations.","e1t":"Görsel sanrılar.","e2":"To suffer from hallucinations.","e2t":"Halüsinasyonlardan muzdarip olmak."},{"w":"haphazard","tr":"rastgele / gelişigüzel / tesadüfi","te":"Adjective","tt":"Sıfat","de":"Not having an obvious order or plan","dt":"Belirli bir düzeni veya planı olmayan","e1":"In a haphazard way.","e1t":"Gelişigüzel bir şekilde.","e2":"A haphazard collection of books.","e2t":"Rastgele bir kitap koleksiyonu."},{"w":"hapless","tr":"talihsiz / bahtsız / kısmetsiz","te":"Adjective","tt":"Sıfat","de":"Unlucky and usually deserving pity","dt":"Şanssız ve genellikle acınmayı hak eden","e1":"Hapless victims of the earthquake.","e1t":"Depremin talihsiz kurbanları.","e2":"A hapless attempt.","e2t":"Başarısız (bahtsız) bir girişim."},{"w":"hardy","tr":"dayanıklı / dirençli / gürbüz","te":"Adjective","tt":"Sıfat","de":"Able to survive difficult conditions","dt":"Zor koşullarda hayatta kalabilen","e1":"Hardy plants that can survive the winter.","e1t":"Kışın hayatta kalabilen dayanıklı bitkiler.","e2":"A hardy breed of sheep.","e2t":"Dirençli bir koyun cinsi."},{"w":"harrowing","tr":"üzücü / yürek yakıcı / dehşet verici","te":"Adjective","tt":"Sıfat","de":"Extremely upsetting or frightening","dt":"Son derece üzücü veya korkutucu","e1":"A harrowing experience.","e1t":"Yürek yakıcı bir deneyim.","e2":"A harrowing tale of survival.","e2t":"Dehşet verici bir hayatta kalma hikayesi."},{"w":"haughty","tr":"kibirli / mağrur / kendini beğenmiş","te":"Adjective","tt":"Sıfat","de":"Unfriendly and seeming to consider yourself better than others","dt":"Dostça olmayan ve kendini diğerlerinden üstün gören","e1":"A haughty look.","e1t":"Kibirli bir bakış.","e2":"He was rather haughty with the servants.","e2t":"Hizmetçilere karşı oldukça kibirliydi."},{"w":"haven","tr":"sığınak / liman / huzurlu yer","te":"Noun","tt":"İsim","de":"A safe or peaceful place","dt":"Güvenli veya huzurlu yer","e1":"The garden is a haven of peace.","e1t":"Bahçe huzurlu bir sığınaktır.","e2":"Tax haven.","e2t":"Vergi cenneti."},{"w":"havoc","tr":"yıkım / kargaşa / tahribat","te":"Noun","tt":"İsim","de":"Confusion and lack of order, especially causing damage","dt":"Özellikle hasara neden olan karışıklık ve düzensizlik","e1":"The storm caused havoc in the garden.","e1t":"Fırtına bahçede tahribata (yıkıma) yol açtı.","e2":"To play havoc with (to ruin).","e2t":"Altüst etmek (mahvetmek)."},{"w":"hearsay","tr":"söylenti / kulaktan dolma bilgi","te":"Noun","tt":"İsim","de":"Information that you have heard but do not know to be true","dt":"Duyduğunuz ancak doğruluğunu bilmediğiniz bilgi","e1":"I can't judge him based on hearsay.","e1t":"Onu söylentilere dayanarak yargılayamam.","e2":"Hearsay evidence (legal).","e2t":"Kulaktan dolma (ikincil) delil."},{"w":"hectic","tr":"yoğun / telaşlı / hareketli","te":"Adjective","tt":"Sıfat","de":"Full of activity, or very busy and fast","dt":"Faaliyet dolu veya çok meşgul ve hızlı","e1":"A hectic day at the office.","e1t":"Ofiste yoğun (telaşlı) bir gün.","e2":"Life in the city is very hectic.","e2t":"Şehirde hayat çok hareketli."},{"w":"heinous","tr":"iğrenç / canice / nefret uyandırıcı (suç)","te":"Adjective","tt":"Sıfat","de":"Very bad and shocking (especially of a crime)","dt":"Çok kötü ve şoke edici (özellikle suç için)","e1":"A heinous crime against humanity.","e1t":"İnsanlığa karşı işlenmiş iğrenç bir suç.","e2":"Heinous acts of violence.","e2t":"Nefret uyandırıcı şiddet eylemleri."},{"w":"herald","tr":"müjdelemek / haber vermek / haberci / elçi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be a sign that something is going to happen; or a messenger","dt":"Bir şeyin olacağının işareti olmak; veya haberci","e1":"The invention heralded a new era.","e1t":"İcat, yeni bir çağın müjdecisi oldu.","e2":"Spring is heralded by the first flowers.","e2t":"Bahar, ilk çiçeklerle haber verilir."},{"w":"hereditary","tr":"kalıtsal / irsi / babadan oğula geçen","te":"Adjective","tt":"Sıfat","de":"Passed from parent to child through genes or as a right","dt":"Genler yoluyla veya hak olarak ebeveynden çocuğa geçen","e1":"A hereditary disease.","e1t":"Kalıtsal bir hastalık.","e2":"Hereditary titles.","e2t":"Babadan oğula geçen (irsi) unvanlar."},{"w":"heresy","tr":"sapkınlık / aykırı görüş","te":"Noun","tt":"İsim","de":"A belief that is against the official principles of a religion","dt":"Bir dinin resmi ilkelerine aykırı olan inanç","e1":"He was burned at the stake for heresy.","e1t":"Sapkınlık suçundan (inancı nedeniyle) yakıldı.","e2":"Political heresy.","e2t":"Siyasi aykırılık."},{"w":"hermetic","tr":"hava geçirmez / dışa kapalı / ezoterik","te":"Adjective","tt":"Sıfat","de":"Sealed so that no air can get in; or closed off from society","dt":"Hava girmemesi için mühürlenmiş; veya toplumdan dışlanmış","e1":"A hermetic seal.","e1t":"Hava geçirmez mühür.","e2":"The hermetic world of the monastery.","e2t":"Manastırın dışa kapalı dünyası."},{"w":"heyday","tr":"en parlak dönem / altın çağ","te":"Noun","tt":"İsim","de":"The time when someone or something was most successful","dt":"Birinin veya bir şeyin en başarılı olduğu zaman","e1":"In the heyday of the Roman Empire.","e1t":"Roma İmparatorluğu'nun en parlak döneminde (altın çağında).","e2":"In his heyday, he was a famous actor.","e2t":"En parlak zamanlarında ünlü bir aktördü."},{"w":"hiatus","tr":"boşluk / ara / kesinti","te":"Noun","tt":"İsim","de":"A short pause in which nothing happens","dt":"Hiçbir şeyin olmadığı kısa bir ara","e1":"After a ten","e1t":"year hiatus, the band reunited.","e2":"On yıllık bir aradan sonra grup tekrar birleşti.","e2t":"A hiatus in the negotiations."},{"w":"hideous","tr":"iğrenç / çok çirkin / korkunç","te":"Adjective","tt":"Sıfat","de":"Very ugly or extremely unpleasant","dt":"Çok çirkin veya son derece nahoş","e1":"A hideous monster.","e1t":"İğrenç (korkunç) bir canavar.","e2":"Hideous crimes.","e2t":"Korkunç suçlar."},{"w":"hinder","tr":"engellemek / aksatmak / mani olmak","te":"Verb","tt":"Fiil","de":"To limit the ability of someone to do something","dt":"Birinin bir şeyi yapma yeteneğini sınırlamak","e1":"High winds hindered the rescue efforts.","e1t":"Güçlü rüzgarlar kurtarma çalışmalarını engelledi.","e2":"To hinder progress.","e2t":"İlerlemeyi aksatmak."},{"w":"hindsight","tr":"sonradan anlama / geçmişe bakınca fark etme","te":"Noun","tt":"İsim","de":"The ability to understand a situation only after it has happened","dt":"Bir durumu ancak gerçekleştikten sonra anlama yeteneği","e1":"With hindsight, I should have taken the job.","e1t":"Şimdi (geçmişe bakınca) anlıyorum ki işi kabul etmeliydim.","e2":"In hindsight, it was a mistake.","e2t":"Geriye dönüp bakınca bunun bir hata olduğu görülüyor."},{"w":"hoard","tr":"istiflemek / biriktirmek / stok yapmak / hazine","te":"Verb/Noun","tt":"Fiil/İsim","de":"To collect and keep large amounts of food or money","dt":"Büyük miktarda yiyecek veya parayı toplayıp saklamak","e1":"People began hoarding food during the war.","e1t":"Savaş sırasında insanlar yiyecek stoklamaya (istiflemeye) başladı.","e2":"A secret hoard of gold coins.","e2t":"Gizli bir altın para hazinesi."},{"w":"hoax","tr":"şaka / hile / asılsız haber / dolandırıcılık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A trick or a plan to deceive people","dt":"İnsanları aldatmak için yapılan plan veya oyun","e1":"The bomb threat was a hoax.","e1t":"Bomba ihbarı asılsızdı (şakaydı).","e2":"A clever internet hoax.","e2t":"Zekice bir internet yalanı."},{"w":"hodgepodge / hotchpotch","tr":"karmakarışık / derme çatma / her telden","te":"Noun","tt":"İsim","de":"A confused mixture of different things","dt":"Farklı şeylerin karmakarışık bir karışımı","e1":"A hodgepodge of different architectural styles.","e1t":"Farklı mimari tarzların derme çatma bir karışımı.","e2":"His room was a hodgepodge of books and clothes.","e2t":"Odası kitap ve kıyafet yığınıydı."},{"w":"holistic","tr":"bütünsel / holistik","te":"Adjective","tt":"Sıfat","de":"Dealing with the whole of something rather than just its parts","dt":"Bir şeyin parçalarından ziyade bütünüyle ilgilenen","e1":"Holistic medicine.","e1t":"Bütünsel tıp.","e2":"A holistic approach to education.","e2t":"Eğitime bütünsel bir yaklaşım."},{"w":"homogeneous","tr":"homojen / tekdüze / bağdaşık","te":"Adjective","tt":"Sıfat","de":"Consisting of parts that are all the same kind","dt":"Hepsi aynı türden parçalardan oluşan","e1":"A homogeneous society.","e1t":"Homojen (tekdüze) bir toplum.","e2":"Homogeneous mixture.","e2t":"Homojen karışım."},{"w":"hospitable","tr":"misafirperver / konuksever / elverişli","te":"Adjective","tt":"Sıfat","de":"Friendly and welcoming to guests; or (of conditions) suitable","dt":"Misafirlere karşı nazik ve sıcak; veya (koşullar için) uygun","e1":"The local people are very hospitable.","e1t":"Yerel halk çok misafirperverdir.","e2":"A hospitable climate for new businesses.","e2t":"Yeni işler için elverişli bir iklim."},{"w":"huddle","tr":"toplanmak / sokulmak / fısıldaşmak / küme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To come close together in a group; or to sit with arms/legs close to body","dt":"Bir grup halinde birbirine yaklaşmak; veya büzülerek oturmak","e1":"The sheep huddled together for warmth.","e1t":"Koyunlar ısınmak için birbirine sokuldu.","e2":"To huddle around the fire.","e2t":"Ateşin etrafında toplanmak."},{"w":"humdrum","tr":"monoton / tekdüze / sıkıcı","te":"Adjective","tt":"Sıfat","de":"Boring and ordinary","dt":"Sıkıcı ve sıradan","e1":"A humdrum existence.","e1t":"Monoton (tekdüze) bir yaşam.","e2":"Humdrum office work.","e2t":"Sıkıcı ofis işleri."},{"w":"humidify","tr":"nemlendirmek","te":"Verb","tt":"Fiil","de":"To make the air more wet","dt":"Havayı daha nemli hale getirmek","e1":"To humidify the room.","e1t":"Odayı nemlendirmek.","e2":"Humidifier (machine).","e2t":"Nemlendirici cihaz."},{"w":"humility","tr":"alçakgönüllülük / tevazu","te":"Noun","tt":"İsim","de":"The quality of not being too proud about yourself","dt":"Kendisiyle aşırı gurur duymama niteliği","e1":"He accepted the award with great humility.","e1t":"Ödülü büyük bir tevazuyla kabul etti.","e2":"Intellectual humility.","e2t":"Entelektüel alçakgönüllülük."},{"w":"hurl","tr":"fırlatmak / savurmak / küfretmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To throw something with a lot of force; or to say insults","dt":"Bir şeyi büyük bir güçle fırlatmak; veya hakaret savurmak","e1":"Protesters hurled stones at the police.","e1t":"Protestocular polise taş fırlattı.","e2":"To hurl abuse at someone.","e2t":"Birine küfür (hakaret) yağdırmak."},{"w":"hyperbole","tr":"abartı / mübalağa","te":"Noun","tt":"İsim","de":"A way of speaking or writing that makes something sound better/more than it is","dt":"Bir şeyi olduğundan daha iyi/fazla gösteren konuşma veya yazı tarzı","e1":"\"I've told you a million times\" is an example of hyperbole.","e1t":"\"Sana bir milyon kez söyledim\" bir abartı örneğidir.","e2":"To use hyperbole.","e2t":"Mübalağa (abartı) kullanmak."},{"w":"hypocrisy","tr":"ikiyüzlülük / riyakarlık","te":"Noun","tt":"İsim","de":"Behavior in which someone pretends to have moral beliefs that they do not really have","dt":"Birinin gerçekte sahip olmadığı ahlaki inançlara sahipmiş gibi davranması","e1":"The hypocrisy of politicians.","e1t":"Siyasetçilerin ikiyüzlülüğü.","e2":"To expose someone's hypocrisy.","e2t":"Birinin riyakarlığını ifşa etmek."},{"w":"hypocrite","tr":"ikiyüzlü / riyakar","te":"Noun","tt":"İsim","de":"A person who acts in a way that goes against what they say","dt":"Söylediklerinin aksine davranan kişi","e1":"He's a hypocrite; he says he likes animals but he wears fur.","e1t":"O bir ikiyüzlü; hayvanları sevdiğini söylüyor ama kürk giyiyor.","e2":"To be a total hypocrite.","e2t":"Tam bir riyakar olmak."},{"w":"iconoclast","tr":"geleneklere karşı gelen / put kırıcı","te":"Noun","tt":"İsim","de":"A person who strongly opposes generally accepted beliefs and traditions","dt":"Genel kabul görmüş inanç ve geleneklere şiddetle karşı çıkan kişi","e1":"As an iconoclast, he challenged all the old rules.","e1t":"Bir kural yıkıcı olarak tüm eski kurallara meydan okudu.","e2":"Iconoclastic views.","e2t":"Geleneklere aykırı görüşler."},{"w":"illicit","tr":"yasadışı / illegal / yasaklanmış","te":"Adjective","tt":"Sıfat","de":"Illegal or disapproved of by society","dt":"Yasadışı veya toplum tarafından onaylanmayan","e1":"Illicit drugs.","e1t":"Yasadışı uyuşturucular.","e2":"An illicit love affair.","e2t":"Yasak (toplum dışı) bir aşk ilişkisi."},{"w":"illiterate","tr":"okuma yazma bilmeyen / cahil","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unable to read and write; or knowing little about a subject","dt":"Okuma yazma bilmeyen; veya bir konu hakkında çok az bilgisi olan","e1":"A large part of the population is illiterate.","e1t":"Nüfusun büyük bir bölümü okuma yazma bilmiyor.","e2":"Computer illiterate.","e2t":"Bilgisayar cahili."},{"w":"imbecile","tr":"aptal / geri zekalı / alık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An extremely stupid person","dt":"Son derece aptal kişi","e1":"He is a total imbecile!","e1t":"O tam bir aptal!","e2":"Imbecile behavior.","e2t":"Aptalca davranış. (Not: Günümüzde kaba bir hakaret olarak kabul edilir)."},{"w":"imbibe","tr":"içmek / özümsemek / içine çekmek","te":"Verb","tt":"Fiil","de":"To drink, especially alcohol; or to receive and accept ideas","dt":"İçmek (özellikle alkol); veya fikirleri özümsemek","e1":"To imbibe a lot of wine.","e1t":"Çok fazla şarap içmek.","e2":"Children quickly imbibe the values of their parents.","e2t":"Çocuklar ebeveynlerinin değerlerini hızla özümserler (kaparlar)."},{"w":"imbue","tr":"aşılamak / doldurmak / telkin etmek","te":"Verb","tt":"Fiil","de":"To fill someone or something with a quality or feeling","dt":"Birini veya bir şeyi bir nitelik veya duyguyla doldurmak","e1":"His poetry is imbued with a sense of sadness.","e1t":"Şiirlerine bir hüzün duygusu aşılanmıştır (hüzünle doludur).","e2":"To imbue someone with confidence.","e2t":"Birine özgüven aşılamak."},{"w":"immaculate","tr":"lekesiz / tertemiz / kusursuz","te":"Adjective","tt":"Sıfat","de":"Perfectly clean or tidy; or without any mistakes","dt":"Kusursuz derecede temiz veya düzenli; veya hatasız","e1":"An immaculate white suit.","e1t":"Lekesiz (tertemiz) beyaz bir takım elbise.","e2":"Her performance was immaculate.","e2t":"Performansı kusursuzdu."},{"w":"immaterial","tr":"önemsiz / konu dışı / cisimsiz / ruhani","te":"Adjective","tt":"Sıfat","de":"Not important or not relevant; or not made of matter","dt":"Önemli veya ilgili olmayan; veya maddi olmayan","e1":"The cost is immaterial.","e1t":"Maliyet önemsizdir (ikincil plandadır).","e2":"Immaterial evidence.","e2t":"Konu dışı delil."},{"w":"immersion","tr":"dalma / batırma / yoğunlaşma","te":"Noun","tt":"İsim","de":"The act of putting something into a liquid; or deep involvement","dt":"Bir şeyi bir sıvıya sokma; veya bir işe çok yoğunlaşma","e1":"Total immersion in a culture.","e1t":"Bir kültürün içine tamamen dalma (onunla bütünleşme).","e2":"Immersion heater.","e2t":"Daldırma ısıtıcı (rezistans)."},{"w":"immutable","tr":"değişmez / kalıcı","te":"Adjective","tt":"Sıfat","de":"Never changing or impossible to change","dt":"Asla değişmeyen veya değişmesi imkansız olan","e1":"The immutable laws of nature.","e1t":"Doğanın değişmez yasaları.","e2":"An immutable decision.","e2t":"Kesin (değiştirilemez) bir karar."},{"w":"impale","tr":"kazığa oturtmak / delip geçmek","te":"Verb","tt":"Fiil","de":"To push a sharp object through something","dt":"Keskin bir nesneyi bir şeyin içinden geçirmek","e1":"The insect was impaled on a pin.","e1t":"Böcek bir iğneye saplanmıştı.","e2":"To impale oneself on a fence.","e2t":"Bir çite saplanmak."},{"w":"impasse","tr":"çıkmaz / düğüm / kördüğüm","te":"Noun","tt":"İsim","de":"A situation in which progress is impossible","dt":"İlerlemenin imkansız olduğu durum","e1":"The negotiations reached an impasse.","e1t":"Müzakereler çıkmaza girdi.","e2":"To break the impasse.","e2t":"Düğümü çözmek (çıkmazı aşmak)."},{"w":"impeccable","tr":"kusursuz / hatasız / mükemmel","te":"Adjective","tt":"Sıfat","de":"Without any faults or mistakes","dt":"Hiçbir hatası veya kusuru olmayan","e1":"She speaks impeccable English.","e1t":"Kusursuz bir İngilizce konuşuyor.","e2":"Impeccable manners.","e2t":"Mükemmel (örnek) davranışlar."},{"w":"impediment","tr":"engel / ayak bağı / konuşma bozukluğu","te":"Noun","tt":"İsim","de":"Something that makes progress difficult; or a physical problem","dt":"İlerlemeyi zorlaştıran şey; veya fiziksel engel","e1":"A serious impediment to economic growth.","e1t":"Ekonomik büyümenin önündeki ciddi bir engel.","e2":"Speech impediment (e.g. stammering).","e2t":"Konuşma bozukluğu (kekemelik vb.)."},{"w":"impending","tr":"yaklaşan / eli kulağında / vuku bulmak üzere","te":"Adjective","tt":"Sıfat","de":"(Of something bad) about to happen soon","dt":"(Kötü bir şey için) yakında gerçekleşmek üzere olan","e1":"The impending storm.","e1t":"Yaklaşan fırtına.","e2":"Warnings of impending disaster.","e2t":"Yaklaşan felaket uyarıları."},{"w":"impermeable","tr":"geçirimsiz / sızdırmaz","te":"Adjective","tt":"Sıfat","de":"Not allowing liquid or gas to pass through","dt":"Sıvı veya gazın geçmesine izin vermeyen","e1":"Impermeable rock.","e1t":"Geçirimsiz kaya.","e2":"This coat is impermeable to water.","e2t":"Bu palto su geçirmezdir."},{"w":"impertinent","tr":"saygısız / terbiyesiz / küstah","te":"Adjective","tt":"Sıfat","de":"Rude and not showing respect, especially to someone older","dt":"Özellikle kendinden büyüklere karşı saygısız veya kaba","e1":"An impertinent question.","e1t":"Saygısızca (yersiz) bir soru.","e2":"Don't be impertinent!","e2t":"Terbiyesizlik etme!"},{"w":"impetus","tr":"itici güç / hız / ivme / teşvik","te":"Noun","tt":"İsim","de":"A force that helps something happen or develop more quickly","dt":"Bir şeyin daha hızlı gerçekleşmesine veya gelişmesine yardımcı olan güç","e1":"The report gave a new impetus to the reform.","e1t":"Rapor, reforma yeni bir itici güç sağladı.","e2":"To lose impetus.","e2t":"Hızını (ivmesini) kaybetmek."},{"w":"impious","tr":"dinsiz / saygısız / Tanrıtanımaz","te":"Adjective","tt":"Sıfat","de":"Not showing respect for God or religion","dt":"Tanrı'ya veya dine saygı göstermeyen","e1":"Impious remarks.","e1t":"Dinsizce (saygısız) sözler.","e2":"An impious act.","e2t":"Dine saygısızlık içeren eylem."},{"w":"implausible","tr":"inanılması güç / mantıksız / akla yatkın olmayan","te":"Adjective","tt":"Sıfat","de":"Difficult to believe or not likely to be true","dt":"İnanması zor veya doğru olması muhtemel olmayan","e1":"An implausible excuse.","e1t":"İnanılması güç (uydurma) bir bahane.","e2":"The plot of the movie is rather implausible.","e2t":"Filmin kurgusu pek akla yatkın değil."},{"w":"imponderable","tr":"ölçülemez / kestirilemez / çok hafif","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Difficult to measure or predict exactly","dt":"Tam olarak ölçülmesi veya tahmin edilmesi zor","e1":"There are too many imponderables in this project.","e1t":"Bu projede çok fazla kestirilemeyen (bilinmez) faktör var.","e2":"Imponderable factors.","e2t":"Ölçülemeyen etkenler."},{"w":"impostor / imposter","tr":"sahtekâr / başkasının adını kullanan / taklitçi","te":"Noun","tt":"İsim","de":"A person who pretends to be someone else to deceive","dt":"Aldatmak için başkasıymış gibi davranan kişi","e1":"The man was discovered to be an impostor.","e1t":"Adamın bir sahtekâr olduğu ortaya çıktı.","e2":"To expose an impostor.","e2t":"Bir sahtekârın maskesini düşürmek."},{"w":"impotent","tr":"güçsüz / aciz / iktidarsız","te":"Adjective","tt":"Sıfat","de":"Lacking power or ability; or (of a man) unable to have sex","dt":"Güç veya yetenekten yoksun; veya (erkek için) cinsel gücü olmayan","e1":"The government was impotent to stop the violence.","e1t":"Hükümet şiddeti durdurmakta aciz kaldı.","e2":"An impotent rage.","e2t":"Çaresiz bir öfke."},{"w":"impregnable","tr":"ele geçirilemez / zapt edilemez / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"So strong that it cannot be entered by force","dt":"Güç kullanılarak girilemeyecek kadar güçlü","e1":"An impregnable fortress.","e1t":"Zapt edilemez bir kale.","e2":"Their lead in the race looked impregnable.","e2t":"Yarıştaki liderlikleri sarsılmaz görünüyordu."},{"w":"impromptu","tr":"doğaçlama / hazırlıksız","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Done without being planned or prepared","dt":"Planlanmadan veya hazırlanmadan yapılan","e1":"An impromptu speech.","e1t":"Hazırlıksız bir konuşma.","e2":"They held an impromptu party.","e2t":"Doğaçlama (bir anda) bir parti verdiler."},{"w":"impropriety","tr":"uygunsuzluk / yolsuzluk / edepsizlik","te":"Noun","tt":"İsim","de":"Behavior that is dishonest or socially unacceptable","dt":"Dürüst olmayan veya toplumsal olarak kabul edilemez davranış","e1":"Financial improprieties.","e1t":"Finansal yolsuzluklar (uygunsuzluklar).","e2":"He was accused of impropriety.","e2t":"Uygunsuz davranışla suçlandı."},{"w":"impudent","tr":"küstah / arsız / saygısız","te":"Adjective","tt":"Sıfat","de":"Rude and not showing respect","dt":"Kaba ve saygısız","e1":"An impudent remark.","e1t":"Küstahça bir söz.","e2":"Stop being so impudent!","e2t":"Bu kadar arsız (küstah) olmayı bırak!"},{"w":"impunity","tr":"cezasız kalma / muafiyet","te":"Noun","tt":"İsim","de":"Freedom from punishment or from the bad results of something","dt":"Cezadan veya kötü sonuçlardan muaf olma durumu","e1":"Criminals act with impunity in this city.","e1t":"Suçlular bu şehirde ceza almayacaklarını bilerek (pervasızca) hareket ediyor.","e2":"You cannot break the rules with impunity.","e2t":"Kuralları ceza almadan bozamazsın."},{"w":"inadvertent","tr":"kasıtsız / yanlışlıkla yapılan","te":"Adjective","tt":"Sıfat","de":"Not intentional","dt":"Kasıtlı olmayan","e1":"An inadvertent mistake.","e1t":"Yanlışlıkla yapılan bir hata.","e2":"Inadvertent disclosure of information.","e2t":"Bilginin kasıtsız (sehven) ifşası."},{"w":"inane","tr":"anlamsız / boş / saçma","te":"Adjective","tt":"Sıfat","de":"Extremely silly or with no real meaning","dt":"Çok aptalca veya gerçek bir anlamı olmayan","e1":"Inane remarks.","e1t":"Boş (saçma) sözler.","e2":"An inane question.","e2t":"Anlamsız bir soru."},{"w":"inanimate","tr":"cansız / ruhsuz","te":"Adjective","tt":"Sıfat","de":"Not alive in the way that people and animals are","dt":"İnsanlar ve hayvanlar gibi canlı olmayan","e1":"An inanimate object.","e1t":"Cansız bir nesne.","e2":"Inanimate nature.","e2t":"Cansız doğa."},{"w":"inarticulate","tr":"kendini ifade edemeyen / anlaşılmaz (konuşma)","te":"Adjective","tt":"Sıfat","de":"Unable to express feelings clearly; or (of speech) not clear","dt":"Duygularını net ifade edemeyen; veya (konuşma için) anlaşılmaz","e1":"He was inarticulate with rage.","e1t":"Öfkeden dili tutulmuştu (kendini ifade edemiyordu).","e2":"An inarticulate mumble.","e2t":"Anlaşılmaz bir mırıldanma."},{"w":"inaugurate","tr":"açılış yapmak / törenle göreve başlatmak / başlatmak","te":"Verb","tt":"Fiil","de":"To put someone into an official position with a ceremony; or to start something","dt":"Birini törenle göreve başlatmak; veya bir şeyi (resmi olarak) başlatmak","e1":"The president was inaugurated today.","e1t":"Başkan bugün törenle göreve başladı.","e2":"To inaugurate a new building.","e2t":"Yeni bir binanın açılışını yapmak."},{"w":"incapacitate","tr":"etkisiz hale getirmek / yetersiz bırakmak","te":"Verb","tt":"Fiil","de":"To make someone unable to work or do things normally","dt":"Birini çalışamaz veya normal şeyleri yapamaz hale getirmek","e1":"The injury incapacitated him for weeks.","e1t":"Sakatlık onu haftalarca iş göremez (etkisiz) kıldı.","e2":"Incapacitated by illness.","e2t":"Hastalık nedeniyle yetersiz kalmış."},{"w":"incarnation","tr":"vücut bulma / somut örnek / enkarnasyon","te":"Noun","tt":"İsim","de":"A person who represents a quality or idea; or a particular life","dt":"Bir niteliği temsil eden kişi; veya (inanışa göre) belirli bir hayat","e1":"She is the incarnation of beauty.","e1t":"O, güzelliğin vücut bulmuş halidir.","e2":"In a previous incarnation.","e2t":"Önceki bir hayatında (reenkarnasyon)."},{"w":"incendiary","tr":"kışkırtıcı / yangın çıkarıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Likely to cause violence or strong feelings; or designed to cause fire","dt":"Şiddete veya güçlü duygulara neden olabilen; veya yangın çıkaran","e1":"Incendiary remarks.","e1t":"Kışkırtıcı (ateşleyici) sözler.","e2":"An incendiary bomb.","e2t":"Yangın bombası."},{"w":"inception","tr":"başlangıç / tesis","te":"Noun","tt":"İsim","de":"The beginning of an organization or official activity","dt":"Bir kuruluşun veya resmi bir faaliyetin başlangıcı","e1":"Since its inception in 2010.","e1t":"2010'daki başlangıcından (kuruluşundan) beri.","e2":"The inception of a project.","e2t":"Bir projenin başlangıç aşaması."},{"w":"incessant","tr":"aralıksız / sürekli / bitmek bilmeyen","te":"Adjective","tt":"Sıfat","de":"Continuing without stopping (usually annoying)","dt":"Durmadan devam eden (genellikle rahatsız edici)","e1":"Incessant rain.","e1t":"Aralıksız yağmur.","e2":"The child's incessant questions.","e2t":"Çocuğun bitmek bilmeyen soruları."},{"w":"inch","tr":"yavaşça ilerlemek / inç (ölçü birimi)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move very slowly or in small steps","dt":"Çok yavaş veya küçük adımlarla ilerlemek","e1":"The climbers inched their way up the cliff.","e1t":"Dağcılar kayalıkta santim santim (yavaşça) ilerlediler.","e2":"To inch closer to a deal.","e2t":"Bir anlaşmaya yavaş yavaş yaklaşmak."},{"w":"inchoate","tr":"henüz gelişmemiş / başlangıç halinde / eksik","te":"Adjective","tt":"Sıfat","de":"Only recently or partly started; not fully formed","dt":"Henüz yeni başlamış; tam şekillenmemiş","e1":"Inchoate ideas.","e1t":"Henüz olgunlaşmamış (başlangıç halindeki) fikirler.","e2":"An inchoate sense of fear.","e2t":"Belirsiz (tam şekillenmemiş) bir korku hissi."},{"w":"incidental","tr":"tesadüfi / ikincil / bağlantılı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Happening as a natural but less important part of something","dt":"Bir şeyin doğal ama daha az önemli bir parçası olarak gerçekleşen","e1":"Incidental expenses.","e1t":"Beklenmedik (küçük) masraflar.","e2":"The risks are incidental to the job.","e2t":"Riskler işin doğasında (bağlantılı) var."},{"w":"incite","tr":"kışkırtmak / teşvik etmek (kötü bir şeye)","te":"Verb","tt":"Fiil","de":"To encourage someone to do something violent or illegal","dt":"Birini şiddete veya yasadışı bir şeye teşvik etmek","e1":"To incite a riot.","e1t":"İsyan kışkırtmak.","e2":"He was accused of inciting racial hatred.","e2t":"Irksal nefreti kışkırtmakla suçlandı."},{"w":"inclusive","tr":"kapsayıcı / dahil","te":"Adjective","tt":"Sıfat","de":"Including everyone; or including the first and last dates/numbers","dt":"Herkesi içeren; veya belirtilen sınırları da kapsayan","e1":"An inclusive society.","e1t":"Kapsayıcı bir toplum.","e2":"From Monday to Friday inclusive.","e2t":"Pazartesi'den Cuma'ya kadar (Cuma dahil)."},{"w":"incognito","tr":"kimliği gizli / takma isimle","te":"Adverb/Adjective","tt":"Travelling or living without letting other people know who you are","de":"Kim olduğunu başkalarına bildirmeden seyahat etme veya yaşama","dt":"The movie star travelled incognito.","e1":"Film yıldızı kimliğini gizleyerek seyahat etti.","e1t":"To remain incognito.","e2":"Gizli kalmak.","e2t":""},{"w":"incoherent","tr":"tutarsız / anlaşılmaz / bağlantısız","te":"Adjective","tt":"Sıfat","de":"Expressed in a way that is not clear or does not make sense","dt":"Net olmayan veya mantıklı gelmeyen bir şekilde ifade edilen","e1":"Incoherent speech.","e1t":"Anlaşılmaz (bağlantısız) konuşma.","e2":"He was so angry he became incoherent.","e2t":"O kadar kızgındı ki dedikleri birbirini tutmuyordu."},{"w":"incongruous","tr":"uyumsuz / yersiz / bağdaşmayan","te":"Adjective","tt":"Sıfat","de":"Unusual or different from the surroundings or what is expected","dt":"Çevreyle veya beklenenle uyumsuz/farklı","e1":"An incongruous sight.","e1t":"Alakasız (uyumsuz) bir görüntü.","e2":"Such a modern building looks incongruous in this old town.","e2t":"Bu kadar modern bir bina bu eski kasabada yersiz görünüyor."},{"w":"inconsequential","tr":"önemsiz / değersiz","te":"Adjective","tt":"Sıfat","de":"Not important","dt":"Önemli olmayan","e1":"Inconsequential details.","e1t":"Önemsiz detaylar.","e2":"An inconsequential amount of money.","e2t":"Kayda değer olmayan bir miktar para."},{"w":"inconsiderate","tr":"düşüncesiz / bencil","te":"Adjective","tt":"Sıfat","de":"Not thinking about other people's feelings or needs","dt":"Diğer insanların duygularını veya ihtiyaçlarını düşünmeyen","e1":"It was inconsiderate of you to keep them waiting.","e1t":"Onları bekletmen düşüncesizlikti.","e2":"Inconsiderate neighbors.","e2t":"Düşüncesiz komşular."},{"w":"incorporeal","tr":"cisimsiz / maddi olmayan / ruhani","te":"Adjective","tt":"Sıfat","de":"Not having a physical body","dt":"Fiziksel bir vücudu olmayan","e1":"Incorporeal beings.","e1t":"Cisimsiz varlıklar (ruhlar).","e2":"Incorporeal property (legal).","e2t":"Maddi olmayan mülkiyet (haklar vb.)."},{"w":"incredulous","tr":"şüpheci / inanmayan / hayret içinde","te":"Adjective","tt":"Sıfat","de":"Not wanting or able to believe something","dt":"Bir şeye inanmak istemeyen veya inanamayan","e1":"An incredulous look.","e1t":"Şüpheci bir bakış.","e2":"He was incredulous when he heard the news.","e2t":"Haberi duyduğunda hayretler içinde kaldı (inanamadı)."},{"w":"increment","tr":"artış / zam / basamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"One of a series of increases","dt":"Bir dizi artıştan biri","e1":"Salary increments.","e1t":"Maaş artışları (zamlar).","e2":"To increase in small increments.","e2t":"Küçük adımlarla (parça parça) artırmak."},{"w":"incriminate","tr":"suçlamak / suçlu göstermek","te":"Verb","tt":"Fiil","de":"To make someone seem guilty of a crime","dt":"Birini bir suçtan suçlu gibi göstermek","e1":"To incriminate oneself.","e1t":"Kendi kendini suçlu duruma düşürmek.","e2":"Incriminating evidence.","e2t":"Suçlayıcı delil."},{"w":"incubate","tr":"kuluçkaya yatmak / (hastalık) kuluçka döneminde olmak","te":"Verb","tt":"Fiil","de":"(Of a bird) to sit on eggs; or (of a virus) to develop","dt":"(Kuş için) yumurtaların üzerine yatmak; veya (virüs için) gelişmek","e1":"The birds are incubating their eggs.","e1t":"Kuşlar yumurtalarının üzerinde kuluçkaya yatıyorlar.","e2":"The virus can incubate for up to two weeks.","e2t":"Virüs iki haftaya kadar kuluçka döneminde kalabilir."},{"w":"incursion","tr":"baskın / istila / tecavüz","te":"Noun","tt":"İsim","de":"A sudden attack or entrance into a place","dt":"Bir yere yapılan ani saldırı veya giriş","e1":"Military incursions.","e1t":"Askeri baskınlar.","e2":"An incursion into enemy territory.","e2t":"Düşman topraklarına sızma (akın)."},{"w":"indict","tr":"dava açmak / suçlamak (resmi)","te":"Verb","tt":"Fiil","de":"To officially charge someone with a crime","dt":"Birini bir suçla resmi olarak itham etmek","e1":"He was indicted for fraud.","e1t":"Dolandırıcılıktan hakkında dava açıldı.","e2":"To indict a suspect.","e2t":"Bir şüpheliyi resmen suçlamak."},{"w":"indiscreet","tr":"patavatsız / ağzı gevşek / düşüncesiz","te":"Adjective","tt":"Sıfat","de":"Saying or doing things that should be kept secret","dt":"Gizli kalması gereken şeyleri söyleyen veya yapan","e1":"An indiscreet remark.","e1t":"Patavatsızca (yersiz) bir söz.","e2":"It was indiscreet of her to tell them the news.","e2t":"Haberi onlara söylemesi düşüncesizlikti."},{"w":"indiscriminate","tr":"ayrım gözetmeyen / rastgele","te":"Adjective","tt":"Sıfat","de":"Done without thought about what the result will be","dt":"Sonucun ne olacağı düşünülmeden (rastgele) yapılan","e1":"Indiscriminate violence.","e1t":"Ayrım gözetmeyen şiddet.","e2":"The indiscriminate use of pesticides.","e2t":"Böcek ilaçlarının rastgele kullanımı."},{"w":"indolent","tr":"tembel / uyuşuk","te":"Adjective","tt":"Sıfat","de":"Lazy","dt":"Tembel","e1":"An indolent student.","e1t":"Tembel bir öğrenci.","e2":"Indolent habits.","e2t":"Uyuşuk alışkanlıklar."},{"w":"indomitable","tr":"yılmaz / pes etmez / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"Brave and determined and impossible to defeat","dt":"Cesur, kararlı ve yenilmesi imkansız","e1":"An indomitable spirit.","e1t":"Yılmaz bir ruh.","e2":"Her indomitable courage.","e2t":"Onun sarsılmaz cesareti."},{"w":"indubitable","tr":"şüphesiz / kesin / kuşku götürmez","te":"Adjective","tt":"Sıfat","de":"That cannot be doubted (formal)","dt":"Şüphe duyulamayacak (resmi)","e1":"An indubitable fact.","e1t":"Şüphe götürmez bir gerçek.","e2":"Indubitable evidence.","e2t":"Kesin delil."},{"w":"indulgent","tr":"hoşgörülü / yüz veren / düşkün","te":"Adjective","tt":"Sıfat","de":"Allowing someone to have what they want (often too much)","dt":"Birinin her istediğine izin veren (genellikle aşırı)","e1":"Indulgent parents.","e1t":"Çocuklarına çok yüz veren ebeveynler.","e2":"To be indulgent toward someone's faults.","e2t":"Birinin hatalarına karşı hoşgörülü olmak."},{"w":"inebriated","tr":"sarhoş","te":"Adjective","tt":"Sıfat","de":"Drunk (formal)","dt":"Sarhoş (resmi)","e1":"He was clearly inebriated.","e1t":"Açıkça sarhoştu.","e2":"To drive while inebriated.","e2t":"Alkollüyken araç kullanmak."},{"w":"inept","tr":"beceriksiz / yeteneksiz / yersiz","te":"Adjective","tt":"Sıfat","de":"Not skilled or effective","dt":"Beceriksiz veya etkisiz","e1":"An inept politician.","e1t":"Beceriksiz bir siyasetçi.","e2":"Socially inept.","e2t":"Sosyal açıdan yeteneksiz (beceriksiz)."},{"w":"inert","tr":"hareketsiz / eylemsiz / durağan","te":"Adjective","tt":"Sıfat","de":"Not moving or not having any energy; or (chemistry) not reacting","dt":"Hareket etmeyen veya enerjisiz; veya (kimya) tepkimeye girmeyen","e1":"He lay inert on the floor.","e1t":"Yerde hareketsiz yatıyordu.","e2":"Inert gases (like neon).","e2t":"Soy gazlar (tepkimeye girmeyen)."},{"w":"inexplicable","tr":"açıklanamaz / izahı olmayan","te":"Adjective","tt":"Sıfat","de":"That cannot be explained","dt":"Açıklanamayan","e1":"For some inexplicable reason.","e1t":"Açıklanamaz (anlaşılmaz) bir nedenden dolayı.","e2":"Inexplicable behavior.","e2t":"İzahi mümkün olmayan davranış."},{"w":"infernal","tr":"cehennem gibi / şeytani / lanet olası","te":"Adjective","tt":"Sıfat","de":"Relating to hell; or very annoying","dt":"Cehennemle ilgili; veya çok sinir bozucu","e1":"The infernal heat of the desert.","e1t":"Çölün cehennem gibi sıcağı.","e2":"Stop that infernal noise!","e2t":"Kes şu lanet olası gürültüyü!"},{"w":"infidel","tr":"kafir / inançsız","te":"Noun","tt":"İsim","de":"A person who does not believe in a particular religion","dt":"Belirli bir dine inanmayan kişi","e1":"To fight the infidels.","e1t":"Kafirlerle savaşmak.","e2":"(Genellikle dini bağlamda aşağılayıcı bir terim olarak kullanılır).","e2t":""},{"w":"infiltrate","tr":"sızmak / sokulmak","te":"Verb","tt":"Fiil","de":"To secretly join a group to get information","dt":"Bilgi almak için gizlice bir gruba katılmak","e1":"Spies managed to infiltrate the organization.","e1t":"Casuslar organizasyona sızmayı başardı.","e2":"Water infiltrates the soil.","e2t":"Su toprağa sızar."},{"w":"inflated","tr":"şişirilmiş / abartılı","te":"Adjective","tt":"Sıfat","de":"(Of prices or ideas) higher than they should be; or filled with air","dt":"(Fiyat veya fikirler için) olması gerekenden yüksek; veya hava ile şişmiş","e1":"Inflated prices.","e1t":"Şişirilmiş fiyatlar.","e2":"An inflated ego.","e2t":"Kabarmış (şişkin) bir ego."},{"w":"infringe","tr":"ihlal etmek / çiğnemek / müdahale etmek","te":"Verb","tt":"Fiil","de":"To break a rule or law; or to limit someone's rights","dt":"Bir kuralı veya yasayı bozmak; veya birinin haklarını sınırlamak","e1":"To infringe a copyright.","e1t":"Telif hakkını ihlal etmek.","e2":"To infringe on someone's privacy.","e2t":"Birinin mahremiyetine müdahale etmek (tecavüz etmek)."},{"w":"infuriate","tr":"çileden çıkarmak / çok kızdırmak","te":"Verb","tt":"Fiil","de":"To make someone extremely angry","dt":"Birini aşırı derecede öfkelendirmek","e1":"It infuriates me when people drive so slowly.","e1t":"İnsanların bu kadar yavaş sürmesi beni çileden çıkarıyor.","e2":"An infuriating delay.","e2t":"Sinir bozucu bir gecikme."},{"w":"ingenious","tr":"dâhiyane / zekice / becerikli","te":"Adjective","tt":"Sıfat","de":"Very intelligent and skillful (of a person or an idea)","dt":"Çok zeki ve becerikli (kişi veya fikir için)","e1":"An ingenious invention.","e1t":"Dâhiyane bir icat.","e2":"An ingenious solution to the problem.","e2t":"Soruna zekice bir çözüm."},{"w":"ingrained","tr":"kökleşmiş / yerleşmiş / işlemiş","te":"Adjective","tt":"Sıfat","de":"(Of beliefs or habits) so established that they are difficult to change","dt":"(İnanç veya alışkanlıklar için) değişmesi zor olacak kadar yerleşmiş","e1":"Ingrained prejudices.","e1t":"Kökleşmiş ön yargılar.","e2":"The habit of hard work was ingrained in him from childhood.","e2t":"Sıkı çalışma alışkanlığı ona çocukluğundan beri işlemişti."},{"w":"ingrate","tr":"nankör / iyilik bilmez","te":"Noun","tt":"İsim","de":"A person who is ungrateful (formal)","dt":"Minnet duymayan, nankör kişi (resmi)","e1":"I don't want to seem like an ingrate, but I expected more.","e1t":"Nankör gibi görünmek istemem ama daha fazlasını bekliyordum.","e2":"A selfish ingrate.","e2t":"Bencil bir nankör."},{"w":"ingratiate","tr":"kendini sevdirmek / yaranmak / göze girmek","te":"Verb","tt":"Fiil","de":"To try to make someone like you, especially to get an advantage","dt":"Özellikle avantaj sağlamak için birine kendini sevdirmeye çalışmak","e1":"He tried to ingratiate himself with the boss.","e1t":"Patrona kendini sevdirmeye (yaranmaya) çalıştı.","e2":"To ingratiate oneself into a group.","e2t":"Bir gruba yaranarak girmek."},{"w":"injunction","tr":"mahkeme emri / ihtiyati tedbir / yasaklama","te":"Noun","tt":"İsim","de":"An official order from a court that stops someone from doing something","dt":"Mahkemeden gelen ve birinin bir şey yapmasını durduran resmi emir","e1":"To seek an injunction against the company.","e1t":"Şirkete karşı mahkeme emri (durdurma kararı) talep etmek.","e2":"A permanent injunction.","e2t":"Kalıcı yasaklama emri."},{"w":"innocuous","tr":"zararsız / masum / etkisiz","te":"Adjective","tt":"Sıfat","de":"Completely harmless or not offensive","dt":"Tamamen zararsız veya kırıcı olmayan","e1":"An innocuous remark.","e1t":"Masum (zararsız) bir söz.","e2":"Most spiders are innocuous.","e2t":"Çoğu örümcek zararsızdır."},{"w":"inquisitive","tr":"meraklı / araştırmacı / çok soru soran","te":"Adjective","tt":"Sıfat","de":"Wanting to discover as much as possible; or too curious","dt":"Mümkün olduğunca çok şey keşfetmek isteyen; veya aşırı meraklı","e1":"An inquisitive child.","e1t":"Meraklı bir çocuk.","e2":"He has an inquisitive mind.","e2t":"Araştırmacı (meraklı) bir zihni var."},{"w":"inroad","tr":"istila / ilerleme / akın / tecavüz","te":"Noun","tt":"İsim","de":"Something that is achieved by reducing the power of something else","dt":"Başka bir şeyin gücünü azaltarak elde edilen ilerleme","e1":"To make inroads into the market.","e1t":"Pazarda ilerleme kaydetmek (pazara sızmak).","e2":"Taxation made inroads into their savings.","e2t":"Vergiler birikimlerini kemirdi (azalttı)."},{"w":"insatiable","tr":"doyumsuz / gözü doymaz","te":"Adjective","tt":"Sıfat","de":"Impossible to satisfy","dt":"Tatmin edilmesi imkansız","e1":"An insatiable appetite for power.","e1t":"Doyumsuz bir güç arzusu.","e2":"Insatiable curiosity.","e2t":"Giderilemez (doyumsuz) merak."},{"w":"inscrutable","tr":"anlaşılmaz / gizemli / okunmaz (yüz ifadesi)","te":"Adjective","tt":"Sıfat","de":"Showing no emotions or clues; impossible to understand","dt":"Hiçbir duygu veya ipucu göstermeyen; anlaşılması imkansız","e1":"An inscrutable expression.","e1t":"Gizemli (ne düşündüğü belli olmayan) bir ifade.","e2":"He remained inscrutable throughout the trial.","e2t":"Duruşma boyunca kapalı bir kutu gibi (anlaşılmaz) kaldı."},{"w":"insensible","tr":"duyarsız / baygın / habersiz / fark edilmeyecek kadar az","te":"Adjective","tt":"Sıfat","de":"Unconscious; or not aware of something; or very small","dt":"Bilinci kapalı; veya bir şeyin farkında olmayan; veya çok küçük","e1":"He fell insensible to the floor.","e1t":"Baygın halde yere düştü.","e2":"Insensible to pain.","e2t":"Acıya karşı duyarsız."},{"w":"insightful","tr":"kavrayışlı / anlayışlı / ferasetli","te":"Adjective","tt":"Sıfat","de":"Showing a clear and deep understanding of something","dt":"Bir şeyi net ve derinlemesine anladığını gösteren","e1":"An insightful comments.","e1t":"Kavrayışlı (derinlikli) yorumlar.","e2":"She is a very insightful observer.","e2t":"O çok ferasetli (keskin gözlemli) bir gözlemcidir."},{"w":"insolvent","tr":"iflas etmiş / borcunu ödeyemeyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not having enough money to pay your debts","dt":"Borçlarını ödeyecek kadar parası olmayan","e1":"The company was declared insolvent.","e1t":"Şirketin iflası istendi (borçlarını ödeyemez ilan edildi).","e2":"To become insolvent.","e2t":"İflas etmek."},{"w":"instigate","tr":"teşvik etmek / başlatmak / kışkırtmak","te":"Verb","tt":"Fiil","de":"To cause an event or situation to happen","dt":"bir olaya veya duruma neden olmak (başlatmak)","e1":"To instigate a reform.","e1t":"Bir reform başlatmak.","e2":"He was accused of instigating the violence.","e2t":"Şiddeti kışkırtmakla suçlandı."},{"w":"instill / instil","tr":"aşılamak / telkin etmek / damlatmak","te":"Verb","tt":"Fiil","de":"To put an idea or a feeling into someone's mind gradually","dt":"Bir fikri veya duyguyu birinin zihnine yavaş yavaş yerleştirmek","e1":"To instill confidence in students.","e1t":"Öğrencilere özgüven aşılamak.","e2":"Parents try to instill good values in their children.","e2t":"Ebeveynler çocuklarına iyi değerler telkin etmeye çalışır."},{"w":"insular","tr":"dar görüşlü / ada ile ilgili / yalıtılmış","te":"Adjective","tt":"Sıfat","de":"Interested only in your own group; or relating to an island","dt":"Sadece kendi grubuyla ilgili; veya ada ile ilgili","e1":"An insular community.","e1t":"Dışa kapalı (yalıtılmış) bir topluluk.","e2":"His insular views on politics.","e2t":"Siyaset konusundaki dar görüşlü yaklaşımları."},{"w":"insurgent","tr":"isyancı / asi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person fighting against the government or army of their own country","dt":"Kendi ülkesinin hükümetine veya ordusuna karşı savaşan kişi","e1":"Insurgent groups.","e1t":"İsyancı gruplar.","e2":"The city was captured by the insurgents.","e2t":"Şehir isyancılar tarafından ele geçirildi."},{"w":"insurmountable","tr":"aşılamaz / baş edilemez","te":"Adjective","tt":"Sıfat","de":"(Of a problem) so great that it cannot be dealt with","dt":"(Sorun için) baş edilemeyecek kadar büyük","e1":"Insurmountable difficulties.","e1t":"Aşılamaz zorluklar.","e2":"The language barrier was not insurmountable.","e2t":"Dil engeli aşılamaz değildi."},{"w":"intercede","tr":"araya girmek / şefaat etmek / arabuluculuk yapmak","te":"Verb","tt":"Fiil","de":"To use your influence to help someone in a difficult situation","dt":"Zor durumdaki birine yardım etmek için nüfuzunu kullanmak","e1":"To intercede with the authorities.","e1t":"Yetkililer nezdinde araya girmek.","e2":"She interceded on his behalf.","e2t":"Onun adına arabuluculuk yaptı (ricacı oldu)."},{"w":"interlocutor","tr":"muhatap / konuşulan kişi","te":"Noun","tt":"İsim","de":"A person who takes part in a conversation (formal)","dt":"Bir konuşmaya katılan kişi (resmi)","e1":"Abraham was his main interlocutor.","e1t":"Abraham onun temel muhatabıydı.","e2":"A reliable interlocutor.","e2t":"Güvenilir bir görüşmeci."},{"w":"interloper","tr":"davetsiz misafir / araya giren / müdahaleci","te":"Noun","tt":"İsim","de":"A person who becomes involved in a place where they are not wanted","dt":"İstenmediği bir yere dahil olan kişi","e1":"They treated me like an interloper.","e1t":"Bana davetsiz misafir (yabancı) gibi davrandılar.","e2":"An unwanted interloper.","e2t":"İstenmeyen müdahaleci."},{"w":"interlude","tr":"ara / fasıl / perde arası (müzik/tiyatro)","te":"Noun","tt":"İsim","de":"A short period of time between two longer periods or events","dt":"İki uzun dönem veya olay arasındaki kısa süre","e1":"A brief interlude of peace.","e1t":"Kısa bir barış arası.","e2":"A musical interlude.","e2t":"Müzikal ara (fasıl)."},{"w":"intermittent","tr":"kesintili / ara sıra olan / durup durup başlayan","te":"Adjective","tt":"Sıfat","de":"Not happening regularly or continuously","dt":"Düzenli veya sürekli olmayan","e1":"Intermittent rain.","e1t":"Yer yer (ara sıra) yağan yağmur.","e2":"An intermittent noise.","e2t":"Kesintili bir gürültü."},{"w":"interrogate","tr":"sorgulamak / soru sormak (resmi)","te":"Verb","tt":"Fiil","de":"To ask someone a lot of questions for a long time in an official way","dt":"Birine resmi bir şekilde uzun süre soru sormak","e1":"The police interrogated the suspect for six hours.","e1t":"Polis şüpheliyi altı saat boyunca sorguladı.","e2":"To interrogate a database.","e2t":"Bir veri tabanını sorgulamak."},{"w":"intertwine","tr":"birbirine dolanmak / iç içe geçmek","te":"Verb","tt":"Fiil","de":"To twist or be twisted together","dt":"Birbirine bükülmek veya dolanmak","e1":"Their lives are closely intertwined.","e1t":"Hayatları birbirine sıkı sıkıya bağlı (iç içe geçmiş).","e2":"Two vines intertwined around the tree.","e2t":"Ağacın etrafına dolanmış iki asma."},{"w":"intractable","tr":"inatçı / baş edilemez / çözülemez","te":"Adjective","tt":"Sıfat","de":"Very difficult or impossible to control, manage, or solve","dt":"Kontrol edilmesi veya çözülmesi çok zor/imkansız","e1":"An intractable problem.","e1t":"Çözülemez bir sorun.","e2":"Intractable pain.","e2t":"Dinmek bilmeyen (inatçı) acı."},{"w":"intrusive","tr":"rahatsız edici / müdahaleci / izinsiz giren","te":"Adjective","tt":"Sıfat","de":"Affecting someone in a way that annoys them and limits their freedom","dt":"Birini rahatsız edecek ve özgürlüğünü kısıtlayacak şekilde etkileyen","e1":"Intrusive questions about my private life.","e1t":"Özel hayatım hakkında rahatsız edici (müdahaleci) sorular.","e2":"Intrusive thoughts.","e2t":"İstenmeyen (rahatsız edici) düşünceler."},{"w":"invalidate","tr":"geçersiz kılmak / çürütmek / hükümsüz bırakmak","te":"Verb","tt":"Fiil","de":"To prove that something is not true or not correct; or to make invalid","dt":"Bir şeyin doğru olmadığını kanıtlamak; veya geçersiz kılmak","e1":"The discovery invalidates previous theories.","e1t":"Keşif, önceki teorileri çürütüyor (geçersiz kılıyor).","e2":"To invalidate a contract.","e2t":"Bir sözleşmeyi feshetmek (geçersiz kılmak)."},{"w":"invective","tr":"hakaret / küfür / sövgü dolu sözler","te":"Noun","tt":"İsim","de":"Criticizing someone in a very loud and angry way","dt":"Birini çok yüksek sesle ve öfkeyle eleştirme (hakaret)","e1":"A stream of invective.","e1t":"Bir dizi küfür (hakaret).","e2":"To pour out invective against someone.","e2t":"Birine hakaretler yağdırmak."},{"w":"invigorate","tr":"canlandırmak / zindelik vermek / güçlendirmek","te":"Verb","tt":"Fiil","de":"To make someone feel fresher, healthier, and more energetic","dt":"Birinin daha taze, sağlıklı ve enerjik hissetmesini sağlamak","e1":"The cold water invigorated him.","e1t":"Soğuk su ona zindelik verdi (canlandırdı).","e2":"To invigorate the economy.","e2t":"Ekonomiyi canlandırmak."},{"w":"invoke","tr":"çağırmak (yardım vb.) / başvurmak (yasa vb.) / uyandırmak","te":"Verb","tt":"Fiil","de":"To use a law or rule; or to ask for help from a god","dt":"Bir yasayı/kuralı kullanmak; veya (Tanrı'dan) yardım dilemek","e1":"To invoke the death penalty.","e1t":"İdam cezasını uygulamaya koymak (başvurmak).","e2":"The smell invoked memories of the past.","e2t":"Koku, geçmişin anılarını uyandırdı (çağırdı)."},{"w":"irate","tr":"öfkeli / çok kızgın","te":"Adjective","tt":"Sıfat","de":"Very angry","dt":"Çok öfkeli","e1":"I received an irate letter from a client.","e1t":"Bir müşteriden öfkeli bir mektup aldım.","e2":"An irate customer.","e2t":"Çok kızgın bir müşteri."},{"w":"ire","tr":"öfke / gazap / hiddet","te":"Noun","tt":"İsim","de":"Anger (formal)","dt":"Öfke (resmi)","e1":"To arouse the ire of the public.","e1t":"Halkın öfkesini çekmek (uyandırmak).","e2":"To be full of ire.","e2t":"Hiddet dolu olmak."},{"w":"jaded","tr":"bıkkın / bezgin / yorgun argın","te":"Adjective","tt":"Sıfat","de":"Not enthusiastic because you have done something too much","dt":"Bir şeyi çok fazla yaptığınız için hevesini kaybetmiş","e1":"I felt a bit jaded after the long trip.","e1t":"Uzun yolculuktan sonra biraz bıkkın (yorgun) hissettim.","e2":"A jaded appetite.","e2t":"Körelmiş (bezgin) bir iştah."},{"w":"jaundiced","tr":"önyargılı / karamsar / sarılık olmuş","te":"Adjective","tt":"Sıfat","de":"Judging someone in an unfair way because of past experience; or yellow","dt":"Geçmiş tecrübeler nedeniyle birini adaletsizce yargılayan; veya sarı","e1":"To take a jaundiced view of politics.","e1t":"Siyasete önyargılı (karamsar) bir gözle bakmak.","e2":"A jaundiced complexion.","e2t":"Sararmış bir ten rengi."},{"w":"jaunt","tr":"kısa gezi / gezinti / kaçamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short journey for pleasure","dt":"Keyif için yapılan kısa yolculuk","e1":"A Sunday jaunt to the seaside.","e1t":"Deniz kenarına yapılan bir Pazar gezintisi.","e2":"To go on a jaunt.","e2t":"Gezintiye çıkmak."},{"w":"jeer","tr":"alay etmek / yuhalamak / alaycı söz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh or shout insults at someone","dt":"Birine gülmek veya hakaret yağdırmak","e1":"The crowd jeered at the players.","e1t":"Kalabalık oyuncuları yuhaladı (onlarla alay etti).","e2":"To greet someone with jeers.","e2t":"Birini alaycı sözlerle karşılamak."},{"w":"jest","tr":"şaka / latife / şakalaşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that is said or done in order to be funny","dt":"Komik olması için söylenen veya yapılan şey","e1":"\"I only said it in jest,\" he explained.","e1t":"\"Sadece şaka olsun diye söyledim,\" diye açıkladı.","e2":"To jest about a serious subject.","e2t":"Ciddi bir konu hakkında şakalaşmak."},{"w":"jingoism","tr":"aşırı milliyetçilik / şovenizm","te":"Noun","tt":"İsim","de":"The belief that your own country is always best","dt":"Kendi ülkesinin her zaman en iyisi olduğuna dair (saldırgan) inanç","e1":"A wave of jingoism.","e1t":"Aşırı milliyetçilik (şovenizm) dalgası.","e2":"Jingoistic slogans.","e2t":"Şovenist sloganlar."},{"w":"jollity","tr":"neşe / eğlence / şenlik","te":"Noun","tt":"İsim","de":"The quality of being happy and cheerful","dt":"Mutlu ve neşeli olma niteliği","e1":"The sounds of jollity coming from the party.","e1t":"Partiden gelen neşe (eğlence) sesleri.","e2":"Festive jollity.","e2t":"Bayram neşesi."},{"w":"jubilant","tr":"coşkulu / sevinçten havalara uçan","te":"Adjective","tt":"Sıfat","de":"Feeling or showing great happiness especially because of a success","dt":"Özellikle bir başarıdan dolayı büyük mutluluk hisseden/gösteren","e1":"The fans were jubilant after the win.","e1t":"Galibiyetten sonra taraftarlar coşku içindeydi.","e2":"A jubilant mood.","e2t":"Sevinç dolu bir ruh hali."},{"w":"judicious","tr":"sağduyulu / makul / yerinde","te":"Adjective","tt":"Sıfat","de":"Having or showing good judgment","dt":"İyi bir muhakeme yeteneğine sahip olan veya gösteren","e1":"A judicious use of resources.","e1t":"Kaynakların sağduyulu (yerinde) kullanımı.","e2":"A judicious decision.","e2t":"Mantıklı (akılcı) bir karar."},{"w":"juggernaut","tr":"durdurulamaz güç / devasa şey / tır (UK)","te":"Noun","tt":"İsim","de":"A very large and powerful force or organization that cannot be stopped","dt":"Durdurulamaz, çok büyük ve güçlü güç veya organizasyon","e1":"The company has become a global juggernaut.","e1t":"Şirket küresel bir deve (durdurulamaz güce) dönüştü.","e2":"A bureaucratic juggernaut.","e2t":"Bürokratik bir canavar (engel)."},{"w":"jurisprudence","tr":"hukuk bilimi / hukuk felsefesi","te":"Noun","tt":"İsim","de":"The study of law and the principles on which laws are based","dt":"Hukuk ve yasaların dayandığı ilkelerin incelenmesi","e1":"Medical jurisprudence.","e1t":"Adli tıp (hukuki boyutu).","e2":"A expert in jurisprudence.","e2t":"Hukuk bilimi uzmanı."},{"w":"kaleidoscope","tr":"çiçek dürbünü / kaleydoskop / sürekli değişen şey","te":"Noun","tt":"İsim","de":"A toy consisting of a tube that you look through to see changing patterns","dt":"Bakıldığında değişen desenler gösteren oyuncak tüp; veya sürekli değişen manzara","e1":"A kaleidoscope of colors.","e1t":"Renk cümbüşü.","e2":"The city offers a kaleidoscope of cultures.","e2t":"Şehir, kültürlerin sürekli değişen bir manzarasını (çeşitliğini) sunuyor."},{"w":"kindred","tr":"akraba / benzer / yakın (fikirsel)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Being related; or having similar ideas or qualities","dt":"Akraba olma; veya benzer fikir/niteliklere sahip olma","e1":"Kindred spirits.","e1t":"Kafa dengi (yakın ruhlu) insanlar.","e2":"Kindred languages.","e2t":"Akraba diller."},{"w":"kiosk","tr":"büfe / kulübe / kiosk (terminal)","te":"Noun","tt":"İsim","de":"A small building where newspapers/sweets are sold; or a computer point","dt":"Gazete/şeker satılan küçük yapı; veya bilgisayar noktası","e1":"To buy a paper at the kiosk.","e1t":"Büfeden gazete almak.","e2":"Information kiosk.","e2t":"Bilgi terminali (kiosk)."},{"w":"knead","tr":"yoğurmak / masaj yapmak","te":"Verb","tt":"Fiil","de":"To press something, especially flour and water, with your hands","dt":"Bir şeyi, özellikle un ve suyu ellerle bastırarak karıştırmak","e1":"To knead dough.","e1t":"Hamur yoğurmak.","e2":"She gently kneaded the muscles in his back.","e2t":"Sırtındaki kaslara nazikçe masaj yaptı (yoğurdu)."},{"w":"knotty","tr":"karmaşık / çetrefilli / düğümlü","te":"Adjective","tt":"Sıfat","de":"(Of a problem) difficult to solve","dt":"(Sorun için) çözülmesi zor","e1":"A knotty problem.","e1t":"Çetrefilli bir sorun.","e2":"Knotty legal issues.","e2t":"Karmaşık hukuki meseleler."},{"w":"kudos","tr":"övgü / takdir / şan","te":"Noun","tt":"İsim","de":"Praise, admiration, and respect received for an achievement","dt":"Bir başarı için alınan övgü, hayranlık ve saygı","e1":"He received a lot of kudos for his work.","e1t":"Çalışması için birçok övgü (takdir) aldı.","e2":"To win kudos.","e2t":"Şan kazanmak."},{"w":"laborious","tr":"zahmetli / meşakkatli / çok emek isteyen","te":"Adjective","tt":"Sıfat","de":"Needing a lot of time and effort","dt":"Çok zaman ve çaba gerektiren","e1":"A laborious task.","e1t":"Zahmetli bir iş.","e2":"The process is slow and laborious.","e2t":"Süreç yavaş ve meşakkatlidir."},{"w":"labyrinth","tr":"labirent / karmaşa","te":"Noun","tt":"İsim","de":"A complicated system of paths; or a very confusing situation","dt":"Karmaşık yollar sistemi; veya çok kafa karıştırıcı bir durum","e1":"A labyrinth of narrow streets.","e1t":"Dar sokaklardan oluşan bir labirent.","e2":"The labyrinth of bureaucracy.","e2t":"Bürokrasi labirenti (karmaşası)."},{"w":"lackadaisical","tr":"isteksiz / gevşek / ilgisiz","te":"Adjective","tt":"Sıfat","de":"Showing a lack of interest, enthusiasm, or effort","dt":"İlgi, heves veya çaba eksikliği gösteren","e1":"A lackadaisical approach to work.","e1t":"İşe karşı gevşek (isteksiz) bir yaklaşım.","e2":"He has a very lackadaisical attitude.","e2t":"Çok ilgisiz bir tavrı var."},{"w":"lackluster / lacklustre","tr":"sönük / donuk / cansız","te":"Adjective","tt":"Sıfat","de":"Lacking energy and effort; not exciting or impressive","dt":"Enerji ve çaba eksikliği olan; heyecan verici veya etkileyici olmayan","e1":"A lackluster performance.","e1t":"Sönük bir performans.","e2":"The company reported lackluster profits.","e2t":"Şirket cansız (beklentinin altında) kârlar bildirdi."},{"w":"laggard","tr":"ağırkanlı / geride kalan / hantal","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person or organization that is slower than others","dt":"Diğerlerinden daha yavaş olan kişi veya kuruluş","e1":"The company is a laggard in the tech industry.","e1t":"Şirket, teknoloji endüstrisinde geride kalan (hantal) bir yapıdadır.","e2":"Economic laggards.","e2t":"Ekonomik olarak geride kalmış ülkeler."},{"w":"lament","tr":"yas tutmak / ağlayıp sızlamak / ağıt","te":"Verb/Noun","tt":"Fiil/İsim","de":"To express sadness and regret about something","dt":"Bir şey hakkında üzüntü ve pişmanlık ifade etmek","e1":"To lament the loss of a friend.","e1t":"Bir dostun kaybına yas tutmak.","e2":"He lamented that he had not worked harder.","e2t":"Daha sıkı çalışmadığı için hayıflandı."},{"w":"lampoon","tr":"hicvetmek / alay etmek / taşlama","te":"Verb/Noun","tt":"Fiil/İsim","de":"To publicly criticize someone by making them look silly","dt":"Birini gülünç duruma düşürerek herkesin önünde eleştirmek","e1":"The magazine is famous for lampooning politicians.","e1t":"Dergi, siyasetçileri hicvetmesiyle ünlüdür.","e2":"A clever lampoon of the film industry.","e2t":"Film endüstrisinin zekice bir taşlaması."},{"w":"languid","tr":"halsiz / uyuşuk / gevşek","te":"Adjective","tt":"Sıfat","de":"Lacking energy, or causing a lack of energy","dt":"Enerjiden yoksun veya enerji eksikliğine neden olan","e1":"A languid afternoon in the sun.","e1t":"Güneş altında geçen uyuşuk bir öğleden sonra.","e2":"He moved in a languid manner.","e2t":"Halsiz (yavaş) bir şekilde hareket etti."},{"w":"languish","tr":"erimek / solmak / acı çekmek (ihmalden)","te":"Verb","tt":"Fiil","de":"To exist in an unpleasant situation for a long time; or to become weak","dt":"Uzun süre nahoş bir durumda kalmak; veya zayıflamak/solmak","e1":"Many people are languishing in prison.","e1t":"Birçok insan hapishanede çürüyor (acı çekiyor).","e2":"The project languished due to lack of funds.","e2t":"Proje, fon yetersizliğinden dolayı atıl kaldı (ilerlemedi)."},{"w":"larceny","tr":"hırsızlık","te":"Noun","tt":"İsim","de":"The crime of stealing something (legal)","dt":"Bir şeyi çalma suçu (hukuki terim)","e1":"He was charged with grand larceny.","e1t":"Büyük çaplı hırsızlıkla suçlandı.","e2":"Petty larceny.","e2t":"Küçük hırsızlık."},{"w":"largess / largesse","tr":"cömertlik / bağış / ulufe","te":"Noun","tt":"İsim","de":"Willingness to give money, or money given to poor people","dt":"Para verme gönüllülüğü veya fakirlere verilen para","e1":"He relied on the largesse of his wealthy friends.","e1t":"Zengin arkadaşlarının cömertliğine güveniyordu.","e2":"Distributed with great largesse.","e2t":"Büyük bir cömertlikle dağıtıldı."},{"w":"lascivious","tr":"şehvetli / ahlaksız / müstehcen","te":"Adjective","tt":"Sıfat","de":"Showing a strong and often unpleasant sexual interest","dt":"Güçlü ve genellikle nahoş bir cinsel ilgi gösteren","e1":"Lascivious behavior.","e1t":"Ahlaksız (şehvet düşkünü) davranış.","e2":"A lascivious look.","e2t":"Müstehcen bir bakış."},{"w":"lassitude","tr":"yorgunluk / bitkinlik / uyuşukluk","te":"Noun","tt":"İsim","de":"Physical or mental tiredness","dt":"Fiziksel veya zihinsel yorgunluk hali","e1":"A feeling of lassitude in the hot weather.","e1t":"Sıcak havada gelen uyuşukluk (bitkinlik) hissi.","e2":"To overcome one's lassitude.","e2t":"Bitkinliğini yenmek."},{"w":"laud","tr":"övmek / methetmek","te":"Verb","tt":"Fiil","de":"To praise someone highly (formal)","dt":"Birini yüksek derecede övmek (resmi)","e1":"He was lauded for his courage.","e1t":"Cesaretinden dolayı methedildi (övüldü).","e2":"A much","e2t":"lauded achievement."},{"w":"laudable","tr":"övgüye değer / takdire şayan","te":"Adjective","tt":"Sıfat","de":"Deserving praise","dt":"Övülmeyi hak eden","e1":"A laudable goal.","e1t":"Övgüye değer bir amaç.","e2":"Her efforts are laudable, but unsuccessful.","e2t":"Çabaları takdire şayan ancak başarısız."},{"w":"lax","tr":"gevşek / lakayıt / ihmalkâr","te":"Adjective","tt":"Sıfat","de":"Not severe or strong enough; careless","dt":"Yeterince sert veya güçlü olmayan; ihmalkâr","e1":"Security at the airport was lax.","e1t":"Havaalanındaki güvenlik gevşekti.","e2":"Lax standards.","e2t":"Düşük (gevşek) standartlar."},{"w":"layperson","tr":"uzman olmayan / sıradan kişi / laik","te":"Noun","tt":"İsim","de":"A person without professional knowledge; or not a member of the clergy","dt":"Profesyonel bilgisi olmayan kişi; veya din adamı olmayan","e1":"To explain complex science to a layperson.","e1t":"Karmaşık bilimi uzman olmayan birine açıklamak.","e2":"A layperson's guide.","e2t":"Sıradan vatandaşın el kitabı."},{"w":"leery","tr":"şüpheci / temkinli / kuşkulu","te":"Adjective","tt":"Sıfat","de":"Not trusting someone or something","dt":"Birine veya bir şeye güvenmeyen","e1":"I'm a bit leery of his promises.","e1t":"Onun vaatlerine karşı biraz şüpheciyim.","e2":"To be leery of strangers.","e2t":"Yabancılara karşı temkinli (kuşkulu) olmak."},{"w":"legion","tr":"çok sayıda / ordu birliği (lejyone)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A large number of people; or a large military unit","dt":"Çok sayıda insan; veya büyük askeri birlik","e1":"His fans are legion (they are many).","e1t":"Hayranlarının sayısı çok fazladır.","e2":"The French Foreign Legion.","e2t":"Fransız Yabancı Lejyonu."},{"w":"legislator","tr":"yasa koyucu / milletvekili","te":"Noun","tt":"İsim","de":"A person who makes laws","dt":"Kanun yapan kişi","e1":"The state legislators.","e1t":"Eyalet yasa koyucuları.","e2":"A group of influential legislators.","e2t":"Bir grup etkili yasa koyucu."},{"w":"lenient","tr":"hoşgörülü / yumuşak / müsamahakar","te":"Adjective","tt":"Sıfat","de":"Not as severe or strong as expected","dt":"Beklendiği kadar sert veya güçlü olmayan","e1":"The judge was very lenient with him.","e1t":"Hakim ona karşı çok hoşgörülü davrandı.","e2":"A lenient punishment.","e2t":"Hafif (yumuşak) bir ceza."},{"w":"lethargic","tr":"uyuşuk / miskin / enerjisiz","te":"Adjective","tt":"Sıfat","de":"Lacking in energy and not wanting to do anything","dt":"Enerjiden yoksun ve hiçbir şey yapmak istemeyen","e1":"I felt tired and lethargic after the flight.","e1t":"Uçuştan sonra yorgun ve uyuşuk hissettim.","e2":"A lethargic economy.","e2t":"Durgun (cansız) bir ekonomi."},{"w":"leverage","tr":"kaldıraç gücü / avantaj sağlamak için kullanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The use of something to maximum advantage","dt":"Bir şeyi maksimum avantaj sağlamak için kullanmak","e1":"We can leverage our position to get a better deal.","e1t":"Daha iyi bir anlaşma için konumumuzu kullanabiliriz.","e2":"Financial leverage.","e2t":"Finansal kaldıraç."},{"w":"levity","tr":"ciddiyetsizlik / hafife alma / şaka","te":"Noun","tt":"İsim","de":"Humor or lack of seriousness, especially about serious things","dt":"Özellikle ciddi konularda gösterilen ciddiyetsizlik veya mizah","e1":"A moment of levity during the trial.","e1t":"Duruşma sırasında yaşanan bir ciddiyetsizlik (mizah) anı.","e2":"To treat the matter with levity.","e2t":"Meseleyi hafife almak (alayla yaklaşmak)."},{"w":"levy","tr":"vergi koymak / toplamak / haciz","te":"Verb/Noun","tt":"Fiil/İsim","de":"To officially demand an amount of money","dt":"Resmi olarak bir miktar para talep etmek (vergilendirmek)","e1":"To levy a tax on tobacco.","e1t":"Tütüne vergi koymak.","e2":"The levy on imports.","e2t":"İthalat vergisi."},{"w":"lewd","tr":"müstehcen / açık saçık / edepsiz","te":"Adjective","tt":"Sıfat","de":"(Of behavior/language) referring to sex in a rude way","dt":"(Davranış/dil için) kaba bir şekilde cinselliğe atıfta bulunan","e1":"Lewd comments.","e1t":"Müstehcen yorumlar.","e2":"Lewd behavior in public.","e2t":"Toplum içinde edepsiz davranış."},{"w":"lexicon","tr":"sözlük / kelime dağarcığı","te":"Noun","tt":"İsim","de":"A list of words; or the words used in a subject","dt":"Kelime listesi; veya bir konuda kullanılan kelimeler","e1":"The legal lexicon.","e1t":"Hukuk terminolojisi (sözlüğü).","e2":"A new word has entered the lexicon.","e2t":"Sözlüğe (dağarcığa) yeni bir kelime girdi."},{"w":"libel","tr":"iftira (yazılı) / hakaret","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of writing that contains false and bad things about someone","dt":"Birisi hakkında yalan ve kötü şeyler içeren yazı","e1":"He sued the newspaper for libel.","e1t":"Gazeteye yazılı iftira davası açtı.","e2":"Libel laws.","e2t":"İftira yasaları. (Not: Sözlü iftiraya 'slander' denir)."},{"w":"libertine","tr":"sefih / ahlaksız / zevk düşkünü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who leads an immoral life and is interested in pleasure","dt":"Ahlaksız bir hayat süren ve zevk düşkünü olan kişi","e1":"He was known as a notorious libertine.","e1t":"Adı çıkmış bir sefih olarak bilinirdi.","e2":"A libertine lifestyle.","e2t":"Sefahat dolu bir yaşam tarzı."},{"w":"licentious","tr":"ahlaksız / kuralsız / şehvet düşkünü","te":"Adjective","tt":"Sıfat","de":"Behaving in a way that is sexually immoral","dt":"Cinsel açıdan ahlaksız bir şekilde davranan","e1":"Licentious behavior.","e1t":"Ahlaksızca davranış.","e2":"A licentious era.","e2t":"Yozlaşmış (kuralsız) bir dönem."},{"w":"liken","tr":"benzetmek","te":"Verb","tt":"Fiil","de":"To say that someone or something is similar to another","dt":"Birini veya bir şeyi başkasına benzetmek","e1":"He likened the crisis to a war.","e1t":"Krizi bir savaşa benzetti.","e2":"Life is often likened to a journey.","e2t":"Hayat genellikle bir yolculuğa benzetilir."},{"w":"limber","tr":"esnek / çevik / ısınmak","te":"Adjective/Verb","tt":"(Of a person) able to bend and move easily","de":"(Kişi için) kolayca eğilebilen ve hareket edebilen","dt":"Limber muscles.","e1":"Esnek kaslar.","e1t":"To limber up before a race.","e2":"Yarıştan önce ısınma hareketleri yapmak (açılmak).","e2t":""},{"w":"limpid","tr":"berrak / net / şeffaf","te":"Adjective","tt":"Sıfat","de":"Clear and transparent","dt":"Berrak ve şeffaf","e1":"Limpid blue water.","e1t":"Berrak mavi su.","e2":"Limpid eyes.","e2t":"Şeffaf (net) gözler."},{"w":"linguist","tr":"dilbilimci / dile yatkın kişi","te":"Noun","tt":"İsim","de":"A person who studies languages or speaks many languages","dt":"Dilleri inceleyen veya birçok dil konuşan kişi","e1":"She is a brilliant linguist.","e1t":"Harika bir dilcidir.","e2":"Applied linguist.","e2t":"Uygulamalı dilbilimci."},{"w":"lionize / lionise","tr":"el üstünde tutmak / kahramanlaştırmak","te":"Verb","tt":"Fiil","de":"To treat someone as very important and admire them","dt":"Birine çok önemli biriymiş gibi davranmak ve hayranlık duymak","e1":"He was lionized by the media.","e1t":"Medya tarafından el üstünde tutuldu (kahramanlaştırıldı).","e2":"To lionize a writer.","e2t":"Bir yazarı göklere çıkarmak."},{"w":"lithe","tr":"kıvrak / esnek / zarif","te":"Adjective","tt":"Sıfat","de":"(Of a body) thin and moving with ease and grace","dt":"(Vücut için) ince ve kolayca, zarafetle hareket eden","e1":"A lithe dancer.","e1t":"Kıvrak bir dansçı.","e2":"Lithe movements.","e2t":"Zarif (esnek) hareketler."},{"w":"litigation","tr":"dava süreci / dava açma","te":"Noun","tt":"İsim","de":"The process of taking a case to a court of law","dt":"Bir davayı mahkemeye taşıma süreci","e1":"The company is involved in litigation.","e1t":"Şirket bir dava sürecine dahil olmuş durumda.","e2":"To avoid litigation.","e2t":"Davalık olmaktan (dava sürecinden) kaçınmak."},{"w":"livid","tr":"çok öfkeli / mosmor / kurşun rengi","te":"Adjective","tt":"Sıfat","de":"Extremely angry; or a dark blue","dt":"grey color","e1":"Çok öfkeli; veya koyu mavi","e1t":"gri renk","e2":"He was livid when he found out.","e2t":"Öğrendiğinde öfkeden kudurdu (mosmor oldu)."},{"w":"loath","tr":"isteksiz / gönülsüz","te":"Adjective","tt":"Sıfat","de":"Not willing to do something","dt":"Bir şeyi yapmaya istekli olmayan","e1":"I was loath to leave the party.","e1t":"Partiden ayrılmaya gönülsüzdüm.","e2":"She is loath to admit her mistakes.","e2t":"Hatalarını kabul etmeye isteksizdir. (Not: 'loathe'"},{"w":"lofty","tr":"yüce / yüksek / kibirli","te":"Adjective","tt":"Sıfat","de":"Very high; or showing a high moral standard; or arrogant","dt":"Çok yüksek; veya yüksek bir ahlaki standart gösteren; veya kibirli","e1":"Lofty ideals.","e1t":"Yüce idealler.","e2":"A lofty mountain peak.","e2t":"Yüksek bir dağ zirvesi."},{"w":"logistics","tr":"lojistik / nakliye ve organizasyon","te":"Noun","tt":"İsim","de":"The careful organization of a complicated activity","dt":"Karmaşık bir faaliyetin dikkatli organizasyonu","e1":"The logistics of moving house.","e1t":"Ev taşımanın lojistiği (organizasyonu).","e2":"Military logistics.","e2t":"Askeri lojistik."},{"w":"loiter","tr":"oyalanmak / aylaklık etmek / boş boş dolaşmak","te":"Verb","tt":"Fiil","de":"To stand or wait somewhere with no obvious reason","dt":"Bir yerde belirgin bir sebep olmadan durmak veya beklemek","e1":"No loitering (sign).","e1t":"Bekleme yapmak (oyalanmak) yasaktır.","e2":"To loiter outside a shop.","e2t":"Bir dükkanın önünde boş boş beklemek."},{"w":"loquacious","tr":"geveze / çok konuşan","te":"Adjective","tt":"Sıfat","de":"Talking a lot (formal)","dt":"Çok konuşan (resmi)","e1":"A loquacious traveling companion.","e1t":"Geveze bir yol arkadaşı.","e2":"He became loquacious after a drink.","e2t":"Bir içkiden sonra dili çözüldü (konuşkanlaştı)."},{"w":"lucid","tr":"açık / anlaşılır / berrak / aklı başında","te":"Adjective","tt":"Sıfat","de":"Clearly expressed and easy to understand; or able to think clearly","dt":"Net ifade edilmiş ve anlaşılması kolay; veya net düşünebilen","e1":"A lucid explanation.","e1t":"Açık ve net bir açıklama.","e2":"Lucid dreaming.","e2t":"Berrak (bilinçli) rüya görme."},{"w":"lugubrious","tr":"hüzünlü / kederli / kasvetli","te":"Adjective","tt":"Sıfat","de":"Sad and serious in a rather exaggerated way","dt":"Oldukça abartılı bir şekilde üzgün ve ciddi","e1":"Lugubrious music.","e1t":"Kederli (kasvetli) müzik.","e2":"A lugubrious expression.","e2t":"Hüzünlü (asık) bir yüz ifadesi."},{"w":"luminary","tr":"aydın kişi / yıldız / duayen","te":"Noun","tt":"İsim","de":"A person who is famous and important in a particular subject","dt":"Belirli bir konuda ünlü ve önemli olan kişi","e1":"Luminaries of the scientific world.","e1t":"Bilim dünyasının önde gelen isimleri (aydınları).","e2":"A legal luminary.","e2t":"Hukuk duayeni."},{"w":"lurid","tr":"ürkütücü / çok parlak (rahatsız edici) / şoke edici","te":"Adjective","tt":"Sıfat","de":"Shocking because of involving violence or sex; or too bright","dt":"Şiddet veya cinsellik içerdiği için şoke edici; veya (renk için) çok parlak","e1":"Lurid details of a murder.","e1t":"Bir cinayetin korkunç (kan donduran) detayları.","e2":"Lurid colors.","e2t":"Göz tırmalayan (çok parlak) renkler."},{"w":"lustrous","tr":"parlak / ışıl ışıl / seçkin","te":"Adjective","tt":"Sıfat","de":"Shining softly; or very impressive","dt":"Yumuşakça parlayan; veya çok etkileyici","e1":"Lustrous hair.","e1t":"Işıl ışıl (parlak) saçlar.","e2":"A lustrous career.","e2t":"Parlak (başarılı) bir kariyer."},{"w":"luxuriant","tr":"verimli / gür / lüks","te":"Adjective","tt":"Sıfat","de":"Growing thickly and strongly; or expensive and attractive","dt":"Gür ve güçlü büyüyen; veya pahalı ve çekici","e1":"Luxuriant vegetation.","e1t":"Gür bitki örtüsü.","e2":"A luxuriant beard.","e2t":"Gür bir sakal."},{"w":"macabre","tr":"ürkütücü / ölümle ilgili / korkunç","te":"Adjective","tt":"Sıfat","de":"Frightening because it is connected with death","dt":"Ölümle bağlantılı olduğu için korkutucu","e1":"A macabre sense of humor.","e1t":"Ürkütücü (ölümle dalga geçen) bir mizah anlayışı.","e2":"A macabre discovery.","e2t":"Korkunç (ölümcül) bir keşif."},{"w":"machination","tr":"entrika / dolap / düzen","te":"Noun","tt":"İsim","de":"A secret and complicated plan to get power or hurt someone","dt":"Güç elde etmek veya birine zarar vermek için yapılan gizli ve karmaşık plan","e1":"Political machinations.","e1t":"Siyasi entrikalar.","e2":"To discover the machinations of the enemy.","e2t":"Düşmanın çevirdiği dolapları ortaya çıkarmak."},{"w":"magnanimous","tr":"yüce gönüllü / alicenap","te":"Adjective","tt":"Sıfat","de":"Kind and generous, especially toward an enemy or rival","dt":"Özellikle bir düşmana veya rakibe karşı nazik ve cömert","e1":"To be magnanimous in victory.","e1t":"Zafer kazandığında yüce gönüllü davranmak.","e2":"A magnanimous gesture.","e2t":"Alicenap (yüce gönüllü) bir jest."},{"w":"magnate","tr":"kodaman / büyük iş adamı / patron","te":"Noun","tt":"İsim","de":"A person who is very rich and powerful in business","dt":"İş dünyasında çok zengin ve güçlü olan kişi","e1":"A shipping magnate.","e1t":"Nakliye kralı (kodamanı).","e2":"A media magnate.","e2t":"Medya patronu."},{"w":"maim","tr":"sakat bırakmak / ağır yaralamak","te":"Verb","tt":"Fiil","de":"To injure someone permanently, especially by losing a limb","dt":"Birini, özellikle bir uzvunu kaybetmesine neden olarak kalıcı şekilde yaralamak","e1":"Many people were maimed by landmines.","e1t":"Birçok insan mayınlar yüzünden sakat kaldı.","e2":"To be maimed for life.","e2t":"Ömür boyu sakat kalmak."},{"w":"maladroit","tr":"beceriksiz / sakar / hantal","te":"Adjective","tt":"Sıfat","de":"Lacking skill or cleverness; clumsy","dt":"Beceri veya zekadan yoksun; sakar","e1":"A maladroit handling of the situation.","e1t":"Durumun beceriksizce idare edilmesi.","e2":"A maladroit remark.","e2t":"Patavatsız (yersiz) bir söz."},{"w":"malaise","tr":"rahatsızlık hissi / huzursuzluk / durgunluk","te":"Noun","tt":"İsim","de":"A general feeling of being ill or unhappy without a clear cause","dt":"Net bir sebebi olmayan genel hastalık veya mutsuzluk hissi","e1":"A general sense of malaise in the country.","e1t":"Ülkede genel bir huzursuzluk (durgunluk) hissi.","e2":"Economic malaise.","e2t":"Ekonomik durgunluk (bozukluk)."},{"w":"malcontent","tr":"hoşnutsuz / memnuniyetsiz / asi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is not satisfied with the way things are","dt":"İşlerin gidişatından memnun olmayan kişi","e1":"The office malcontents.","e1t":"Ofisteki memnuniyetsiz tipler.","e2":"A malcontent employee.","e2t":"Hoşnutsuz bir çalışan."},{"w":"malediction","tr":"lanet / beddua","te":"Noun","tt":"İsim","de":"A wish that something bad will happen to someone; a curse","dt":"Birine kötü bir şey olması dileği; lanet","e1":"He muttered a malediction under his breath.","e1t":"Kendi kendine bir beddua mırıldandı.","e2":"To utter a malediction.","e2t":"Lanet okumak."},{"w":"malefactor","tr":"suçlu / kötülük yapan kişi","te":"Noun","tt":"İsim","de":"A person who does something wrong or illegal (formal)","dt":"Yanlış veya yasadışı bir şey yapan kişi (resmi)","e1":"To punish the malefactors.","e1t":"Suçluları cezalandırmak.","e2":"A notorious malefactor.","e2t":"Adı çıkmış bir suçlu."},{"w":"malfeasance","tr":"görevi kötüye kullanma / yolsuzluk","te":"Noun","tt":"İsim","de":"Wrong or illegal behavior by a public official","dt":"Bir kamu görevlisinin yanlış veya yasadışı davranışı","e1":"He was fired for financial malfeasance.","e1t":"Finansal yolsuzluk nedeniyle kovuldu.","e2":"Corporate malfeasance.","e2t":"Şirket içi görevi kötüye kullanma."},{"w":"malign","tr":"kötülemek / iftira atmak / kötücül","te":"Verb/Adjective","tt":"To say false and bad things about someone; or harmful","de":"Birisi hakkında yalan ve kötü şeyler söylemek; veya zararlı","dt":"She feels she has been much maligned by the press.","e1":"Basın tarafından çok kötülendiğini hissediyor.","e1t":"A malign influence.","e2":"Kötücül (zararlı) bir etki.","e2t":""},{"w":"malinger","tr":"hasta numarası yapmak / kaytarmak","te":"Verb","tt":"Fiil","de":"To pretend to be ill in order to avoid work","dt":"İşten kaçmak için hasta gibi davranmak","e1":"He’s not really ill; he’s just malingering.","e1t":"Gerçekten hasta değil, sadece kaytarıyor (numara yapıyor).","e2":"To be accused of malingering.","e2t":"Hasta numarası yapmakla suçlanmak."},{"w":"malleable","tr":"şekillendirilebilir / uysal / dövülgen","te":"Adjective","tt":"Sıfat","de":"Able to be beaten into a different shape; or easily influenced","dt":"Farklı bir şekle sokulabilen (metal); veya kolayca etkilenen","e1":"Gold is a malleable metal.","e1t":"Altın şekillendirilebilir (dövülgen) bir metaldir.","e2":"A malleable young mind.","e2t":"Kolayca şekillendirilebilen (etkilenebilen) genç bir zihin."},{"w":"malnutrition","tr":"yetersiz beslenme","te":"Noun","tt":"İsim","de":"Physical weakness caused by a lack of food or of the right food","dt":"Yiyecek eksikliği veya yanlış beslenmeden kaynaklanan fiziksel zayıflık","e1":"Many children suffer from malnutrition.","e1t":"Birçok çocuk yetersiz beslenmeden muzdarip.","e2":"To die of malnutrition.","e2t":"Besinsizlikten ölmek."},{"w":"malodorous","tr":"kötü kokulu / kokuşmuş","te":"Adjective","tt":"Sıfat","de":"Having an unpleasant smell (formal)","dt":"Nahoş bir kokusu olan (resmi)","e1":"Malodorous waste.","e1t":"Kötü kokulu atık.","e2":"A malodorous breath.","e2t":"Kokan bir nefes."},{"w":"mammoth","tr":"devasa / çok büyük / mamut","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Extremely large; or an extinct animal like an elephant","dt":"Son derece büyük; veya mamut","e1":"A mammoth task.","e1t":"Dev gibi (çok büyük) bir iş.","e2":"A mammoth project.","e2t":"Devasa bir proje."},{"w":"mania","tr":"çılgınlık / tutku / mani","te":"Noun","tt":"İsim","de":"A very strong interest in something; or a mental illness","dt":"Bir şeye duyulan aşırı ilgi; veya zihinsel hastalık","e1":"A mania for collecting stamps.","e1t":"Pul toplama çılgınlığı.","e2":"Religious mania.","e2t":"Dini cinnet (çılgınlık)."},{"w":"manifesto","tr":"bildiri / manifesto / beyanname","te":"Noun","tt":"İsim","de":"A written statement of the beliefs and plans of a group","dt":"Bir grubun inanç ve planlarını içeren yazılı beyan","e1":"The party's election manifesto.","e1t":"Partinin seçim beyannamesi.","e2":"To publish a manifesto.","e2t":"Bir manifesto yayınlamak."},{"w":"manifold","tr":"çeşitli / çok yönlü / manifolt","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Many and of different kinds","dt":"Çok sayıda ve farklı türde","e1":"The reasons for this change are manifold.","e1t":"Bu değişimin nedenleri çok çeşitlidir.","e2":"Manifold responsibilities.","e2t":"Çok yönlü sorumluluklar."},{"w":"mannerism","tr":"kendine özgü tavır / yapmacıklık","te":"Noun","tt":"İsim","de":"A peculiar way of acting or speaking","dt":"Kendine has, bazen tuhaf olan konuşma veya davranış tarzı","e1":"He has an annoying mannerism of clicking his fingers.","e1t":"Parmaklarını şıklatmak gibi sinir bozucu bir alışkanlığı (tavrı) var.","e2":"Artistic mannerisms.","e2t":"Sanatsal yapmacıklıklar (üslup özellikleri)."},{"w":"mantle","tr":"örtü / pelerin / üstlenme (sorumluluk) / manto (yerküre)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A layer that covers something; or a position of authority","dt":"Bir şeyi örten tabaka; veya yetki/sorumluluk konumu","e1":"A mantle of snow.","e1t":"Kar örtüsü.","e2":"To take up the mantle of leadership.","e2t":"Liderlik sorumluluğunu (görevini) üstlenmek."},{"w":"mar","tr":"bozmak / lekelemek / zarar vermek","te":"Verb","tt":"Fiil","de":"To spoil something, making it less perfect","dt":"Bir şeyi bozmak, kusursuzluğunu gidermek","e1":"The game was marred by violence.","e1t":"Oyun şiddet olaylarıyla gölgelendi (bozuldu).","e2":"A face marred by scars.","e2t":"Yara izleriyle bozulmuş bir yüz."},{"w":"maraud","tr":"yağmalamak / çapulculuk etmek","te":"Verb","tt":"Fiil","de":"To roam around in search of things to steal or people to attack","dt":"Çalacak şey veya saldıracak insan arayarak etrafta dolaşmak","e1":"Marauding gangs.","e1t":"Yağmacı çeteler.","e2":"To maraud through the countryside.","e2t":"Kırsal alanı yağmalayarak geçmek."},{"w":"marked","tr":"belirgin / göze çarpan / fişlenmiş","te":"Adjective","tt":"Sıfat","de":"Very easy to notice; or clearly defined","dt":"Fark edilmesi çok kolay; veya net şekilde belirlenmiş","e1":"A marked improvement in her work.","e1t":"İşinde belirgin bir düzelme.","e2":"He is a marked man (police are watching him).","e2t":"O fişlenmiş (takipte) bir adam."},{"w":"marred","tr":"bozulmuş / hasarlı / gölgelenmiş","te":"Adjective","tt":"Sıfat","de":"Damaged or spoiled","dt":"Zarar görmüş veya bozulmuş","e1":"A holiday marred by bad weather.","e1t":"Kötü hava nedeniyle tadı kaçmış (gölgelenmiş) bir tatil.","e2":"Her beauty was marred by a small scar.","e2t":"Güzelliği küçük bir yara iziyle gölgelenmişti."},{"w":"martinet","tr":"disiplin manyağı / aşırı sert amir","te":"Noun","tt":"İsim","de":"Someone who demands that rules are obeyed very strictly","dt":"Kurallara çok sıkı uyulmasını isteyen kişi","e1":"The new principal is a real martinet.","e1t":"Yeni müdür tam bir disiplin manyağı.","e2":"A military martinet.","e2t":"Çok sert bir subay."},{"w":"masquerade","tr":"maskeli balo / gizlenmek /","te":"miş gibi yapmak","tt":"Noun/Verb","de":"İsim/Fiil","dt":"A party where people wear masks; or a false appearance","e1":"Maskeli balo; veya yanıltıcı dış görünüş","e1t":"He masqueraded as a doctor.","e2":"Doktor kılığında dolaştı (doktor taklidi yaptı).","e2t":"To keep up the masquerade."},{"w":"maudlin","tr":"aşırı duygusal / sulugöz / (içkiliyken) ağlayan","te":"Adjective","tt":"Sıfat","de":"Feeling or showing too much emotion, often in a silly way","dt":"Genellikle saçma bir şekilde aşırı duygusallık gösteren","e1":"He gets maudlin after a few drinks.","e1t":"Birkaç içkiden sonra sulugöz (aşırı duygusal) olur.","e2":"A maudlin poem.","e2t":"Aşırı duygusal (vıcık vıcık) bir şiir."},{"w":"maul","tr":"hırpalamak / pençelemek / ağır eleştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To attack someone and cause a serious injury","dt":"Birine saldırıp ağır yaralamak; veya yerden yere vurmak","e1":"The boy was mauled by a lion.","e1t":"Çocuk bir aslan tarafından hırpalandı (parçalandı).","e2":"The film was mauled by the critics.","e2t":"Film eleştirmenler tarafından yerden yere vuruldu."},{"w":"maverick","tr":"başına buyruk / özgün / aykırı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who thinks and acts in an independent way","dt":"Bağımsız düşünen ve hareket eden (sıra dışı) kişi","e1":"A political maverick.","e1t":"Bağımsız (aykırı) siyasetçi.","e2":"He has always been a bit of a maverick.","e2t":"Her zaman biraz başına buyruk biri olmuştur."},{"w":"mawkish","tr":"aşırı duygusal / vıcık vıcık / baygın","te":"Adjective","tt":"Sıfat","de":"Showing too much emotion in a way that is unpleasant","dt":"Nahoş bir şekilde aşırı duygusallık gösteren","e1":"A mawkish love story.","e1t":"Vıcık vıcık (saçma derece duygusal) bir aşk hikayesi.","e2":"Mawkish sentimentality.","e2t":"Baygın bir duygusallık."},{"w":"maxim","tr":"özdeyiş / düstur / kural","te":"Noun","tt":"İsim","de":"A short statement of a general truth or rule of behavior","dt":"Genel bir gerçeğin veya davranış kuralının kısa ifadesi","e1":"\"Waste not, want not\" is a popular maxim.","e1t":"\"İsraf etmeyen muhtaç olmaz\" popüler bir özdeyiştir.","e2":"To follow the maxim.","e2t":"Düsturu takip etmek."},{"w":"meddlesome","tr":"her şeye karışan / işgüzar / fuzuli","te":"Adjective","tt":"Sıfat","de":"Often getting involved in situations where you are not wanted","dt":"İstenmediği halde sürekli başkalarının işine karışan","e1":"A meddlesome neighbor.","e1t":"Her şeye burnunu sokan (işgüzar) komşu.","e2":"Stop being so meddlesome!","e2t":"Bu kadar işgüzar olmayı bırak!"},{"w":"medley","tr":"karışım / seçmece / karışık (spor)","te":"Noun","tt":"İsim","de":"A mixture of different things, especially songs or sports","dt":"Farklı şeylerin (özellikle şarkıların) karışımı","e1":"A medley of popular hits.","e1t":"Popüler şarkılardan oluşan bir karışım.","e2":"400","e2t":"meter individual medley (swimming)."},{"w":"melee","tr":"arbede / kargaşa / kavga","te":"Noun","tt":"İsim","de":"A confused fight or struggle among a lot of people","dt":"Çok sayıda insan arasındaki karışık kavga veya arbede","e1":"Several people were hurt in the melee.","e1t":"Arbedede birkaç kişi yaralandı.","e2":"To be caught in the melee.","e2t":"Kargaşanın ortasında kalmak."},{"w":"mellifluous","tr":"kulağa hoş gelen / tatlı / bal gibi","te":"Adjective","tt":"Sıfat","de":"(Of a voice or music) smooth and pleasant to listen to","dt":"(Ses veya müzik için) dinlemesi hoş ve yumuşak","e1":"A mellifluous voice.","e1t":"Tatlı (kulağa hoş gelen) bir ses.","e2":"The mellifluous sound of the cello.","e2t":"Çellonun kulağa hoş gelen sesi."},{"w":"memento","tr":"hatıra / yadigar","te":"Noun","tt":"İsim","de":"An object kept as a reminder of a person or event","dt":"Bir kişiyi veya olayı hatırlatan nesne","e1":"I kept the menu as a memento of our dinner.","e1t":"Menüyü yemeğimizin bir hatırası olarak sakladım.","e2":"A memento of his trip.","e2t":"Gezisinin bir yadigarı."},{"w":"memoir","tr":"anı yazısı / özgeçmiş / hatırat","te":"Noun","tt":"İsim","de":"A book written by someone about their own life and experiences","dt":"Birinin kendi hayatı ve tecrübeleri hakkında yazdığı kitap","e1":"She is writing her memoirs.","e1t":"Hatıralarını (anılarını) yazıyor.","e2":"A political memoir.","e2t":"Siyasi hatırat."},{"w":"menagerie","tr":"hayvanat bahçesi (eski) / vahşi hayvan koleksiyonu","te":"Noun","tt":"İsim","de":"A collection of wild animals kept in cages (historical)","dt":"Kafeslerde tutulan vahşi hayvan koleksiyonu (tarihi terim)","e1":"A private menagerie.","e1t":"Özel hayvan koleksiyonu.","e2":"The circus had a small menagerie.","e2t":"Sirkin küçük bir hayvan koleksiyonu vardı."},{"w":"mendacious","tr":"yalancı / doğru olmayan","te":"Adjective","tt":"Sıfat","de":"Not telling the truth; dishonest (formal)","dt":"Gerçeği söylemeyen; dürüst olmayan (resmi)","e1":"A mendacious report.","e1t":"Yalan (yanıltıcı) bir rapor.","e2":"Mendacious propaganda.","e2t":"Yalancı propaganda."},{"w":"mendicant","tr":"dilenci / dilenen rahip","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who survives by asking for money; a beggar","dt":"Para isteyerek hayatta kalan kişi; dilenci","e1":"Mendicant friars.","e1t":"Dilenci rahipler.","e2":"The city's mendicant population.","e2t":"Şehrin dilenci nüfusu."},{"w":"menial","tr":"önemsiz (iş) / sıkıcı ve düşük statülü","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of work) boring, needing little skill, and of low status","dt":"(İş için) sıkıcı, beceri gerektirmeyen ve düşük statülü","e1":"Menial tasks like cleaning floors.","e1t":"Yerleri silmek gibi ayak işleri (önemsiz işler).","e2":"A menial job.","e2t":"Düşük statülü (sıkıcı) bir iş."},{"w":"mercenary","tr":"paralı asker / çıkarcı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A soldier who fights for a foreign country for money; or interested only in money","dt":"Para için savaşan asker; veya sadece parayla ilgilenen","e1":"He had purely mercenary motives.","e1t":"Tamamen çıkarcı (paraya dayalı) motifleri vardı.","e2":"Mercenary troops.","e2t":"Paralı asker birlikleri."},{"w":"mercurial","tr":"değişken ruhlu / kararsız / cıva gibi","te":"Adjective","tt":"Sıfat","de":"Changing mood or behavior suddenly and quickly","dt":"Ruh hali veya davranışı aniden ve hızla değişen","e1":"His mercurial temperament.","e1t":"Onun değişken (istikrarsız) huyu.","e2":"A mercurial personality.","e2t":"Kararsız bir kişilik."},{"w":"meritorious","tr":"övgüye değer / takdire şayan","te":"Adjective","tt":"Sıfat","de":"Deserving praise (formal)","dt":"Övgüyü hak eden (resmi)","e1":"Meritorious conduct.","e1t":"Övgüye değer davranış.","e2":"A meritorious achievement.","e2t":"Takdire şayan bir başarı."},{"w":"merriment","tr":"neşe / eğlence / şenlik","te":"Noun","tt":"İsim","de":"Laughter and enjoyment","dt":"Gülüşme ve eğlence","e1":"The sound of merriment coming from upstairs.","e1t":"Üst kattan gelen neşe sesleri.","e2":"Festive merriment.","e2t":"Bayram neşesi."},{"w":"mesmerize / mesmerise","tr":"büyülemek / hipnotize etmek","te":"Verb","tt":"Fiil","de":"To have someone's attention completely so they cannot think of anything else","dt":"Birinin tüm dikkatini başka bir şey düşünemeyecek şekilde çekmek","e1":"I was mesmerized by her performance.","e1t":"Performansı karşısında büyülendim.","e2":"A mesmerizing sight.","e2t":"Büyüleyici bir görüntü."},{"w":"metamorphosis","tr":"başkalaşım / değişim / metamorfoz","te":"Noun","tt":"İsim","de":"A complete change of physical form or character","dt":"Fiziksel biçimin veya karakterin tamamen değişmesi","e1":"The metamorphosis of a caterpillar into a butterfly.","e1t":"Bir tırtılın kelebeğe dönüşmesi (başkalaşımı).","e2":"A complete political metamorphosis.","e2t":"Tam bir siyasi değişim."},{"w":"metaphysical","tr":"fizikötesi / soyut / metafiziksel","te":"Adjective","tt":"Sıfat","de":"Relating to the part of philosophy that studies the nature of existence","dt":"Varlığın doğasını inceleyen felsefe dalı ile ilgili","e1":"Metaphysical poetry.","e1t":"Metafizik şiir.","e2":"A metaphysical question.","e2t":"Fizikötesi (soyut) bir soru."},{"w":"mettle","tr":"cesaret / karakter / yüreklilik","te":"Noun","tt":"İsim","de":"Bravery and determination","dt":"Cesaret ve kararlılık","e1":"To show one's mettle.","e1t":"Rüştünü ispat etmek (cesaretini göstermek).","e2":"The next game will be a real test of their mettle.","e2t":"Bir sonraki maç onların yürekliliğinin gerçek bir testi olacak."},{"w":"miasma","tr":"kötü hava / nahoş atmosfer / pis koku","te":"Noun","tt":"İsim","de":"An unpleasant fog; or a bad atmosphere surrounding something","dt":"Nahoş bir sis; veya bir şeyi çevreleyen kötü atmosfer","e1":"A miasma of corruption.","e1t":"Yolsuzluk bataklığı (atmosferi).","e2":"The miasma rising from the swamp.","e2t":"Bataklıktan yükselen pis koku (buhar)."},{"w":"microcosm","tr":"küçük evren / küçük örnek","te":"Noun","tt":"İsim","de":"A small place or situation that has the same features as something much larger","dt":"Daha büyük bir şeyin özelliklerine sahip olan küçük örnek","e1":"The school is a microcosm of society.","e1t":"Okul, toplumun küçük bir örneğidir (minyatürüdür).","e2":"In microcosm.","e2t":"Küçük ölçekte."},{"w":"migratory","tr":"göçmen / göçer","te":"Adjective","tt":"Sıfat","de":"Relating to animals that move from one place to another at different times of the year","dt":"Yılın farklı zamanlarında bir yerden başka bir yere giden hayvanlarla ilgili","e1":"Migratory birds.","e1t":"Göçmen kuşlar.","e2":"The migratory patterns of whales.","e2t":"Balinaların göç yolları (paternleri)."},{"w":"milieu","tr":"çevre / ortam / sosyal çevre","te":"Noun","tt":"İsim","de":"The social environment that you live or work in","dt":"Yaşadığınız veya çalıştığınız sosyal ortam","e1":"She felt out of place in such a high","e1t":"society milieu.","e2":"Öyle yüksek bir sosyete ortamında kendini yabancı hissetti.","e2t":"A cultural milieu."},{"w":"militate","tr":"etkili olmak (aleyhine) / engel olmak","te":"Verb","tt":"Fiil","de":"To make something less likely to happen (used with \"against\")","dt":"Bir şeyin gerçekleşme ihtimalini azaltmak (\"against\" ile kullanılır)","e1":"Several factors militate against the success of the plan.","e1t":"Birkaç faktör planın başarısına engel teşkil ediyor (aleyhine işliyor).","e2":"","e2t":""},{"w":"mimicry","tr":"taklit / taklitçilik / kamuflaj","te":"Noun","tt":"İsim","de":"The act of copying someone's behavior; or an animal's ability to look like another","dt":"Birinin davranışını kopyalama; veya bir hayvanın diğerine benzeme yeteneği","e1":"He is a master of mimicry.","e1t":"O bir taklit ustasıdır.","e2":"Protective mimicry in insects.","e2t":"Böceklerde koruyucu kamuflaj (taklit)."},{"w":"minatory","tr":"tehditkar / korkutucu","te":"Adjective","tt":"Sıfat","de":"Expressing a threat (formal)","dt":"Tehdit içeren (resmi)","e1":"He sent a minatory letter to his rivals.","e1t":"Rakiplerine tehditkar bir mektup gönderdi.","e2":"A minatory gesture.","e2t":"Korkutucu bir el hareketi."},{"w":"minion","tr":"dalkavuk / uşak / köle (emir kulu)","te":"Noun","tt":"İsim","de":"A person who is not important and has to do what a powerful person says","dt":"Önemli olmayan ve güçlü birinin dediklerini yapan kişi","e1":"He sent one of his minions to do the work.","e1t":"İşi yapması için emir kullarından birini gönderdi.","e2":"Political minions.","e2t":"Siyasi yaltakçılar."},{"w":"minuscule","tr":"küçücük / minnacık / çok küçük","te":"Adjective","tt":"Sıfat","de":"Extremely small","dt":"Son derece küçük","e1":"A minuscule amount of food.","e1t":"Minnacık bir miktar yemek.","e2":"Minuscule handwriting.","e2t":"Küçücük (okunması zor) el yazısı."},{"w":"mirage","tr":"serap / yanılsama / hayal","te":"Noun","tt":"İsim","de":"An image that seems real but is not there, especially in a desert","dt":"Özellikle çölde gerçek gibi görünen ama olmayan görüntü","e1":"The oasis turned out to be a mirage.","e1t":"Vaha bir serap çıktı.","e2":"A mirage of hope.","e2t":"Bir hayal (yanılsama) olan umut."},{"w":"mire","tr":"bataklık / çamur / zor durum","te":"Noun/Verb","tt":"İsim/Fiil","de":"An area of deep, wet, sticky earth; or a difficult situation","dt":"Derin, ıslak ve yapışkan toprak alanı; veya zor bir durum","e1":"To be caught in the mire.","e1t":"Bataklığa (veya zor bir duruma) saplanmak.","e2":"The company is sinking into a financial mire.","e2t":"Şirket finansal bir bataklığa gömülüyor."},{"w":"misanthrope","tr":"insanlardan nefret eden / insan sevmez","te":"Noun","tt":"İsim","de":"A person who dislikes or avoids other people","dt":"Diğer insanlardan hoşlanmayan veya onlardan kaçınan kişi","e1":"He lived as a misanthrope in a remote cottage.","e1t":"Uzak bir kulübede insan sevmez biri olarak yaşadı.","e2":"Misanthropic views.","e2t":"İnsan sevmeyen görüşler."},{"w":"misapprehension","tr":"yanlış anlama / yanılgı","te":"Noun","tt":"İsim","de":"A failure to understand something correctly","dt":"Bir şeyi doğru şekilde anlayamama hali","e1":"I was under the misapprehension that the meeting was today.","e1t":"Toplantının bugün olduğu yanılgısı içindeydim.","e2":"To clear up a misapprehension.","e2t":"Bir yanlış anlaşılmayı düzeltmek."},{"w":"misbegotten","tr":"gayrimeşru / kötü planlanmış / talihsiz","te":"Adjective","tt":"Sıfat","de":"Badly planned or thought about; or born of parents not married","dt":"Kötü planlanmış; veya evli olmayan ebeveynlerden doğan","e1":"A misbegotten scheme.","e1t":"Kötü düşünülmüş (talihsiz) bir plan.","e2":"Misbegotten children.","e2t":"Gayrimeşru çocuklar."},{"w":"miscellany","tr":"karışık derleme / karma / antoloji","te":"Noun","tt":"İsim","de":"A mixture of various different things or writings","dt":"Çeşitli farklı şeylerin veya yazıların karışımı","e1":"A miscellany of old poems.","e1t":"Eski şiirlerden oluşan bir derleme (karma).","e2":"An interesting miscellany of information.","e2t":"İlginç bir bilgi karması."},{"w":"misconstrue","tr":"yanlış yorumlamak / yanlış anlamak","te":"Verb","tt":"Fiil","de":"To understand someone's words or actions wrongly","dt":"Birinin sözlerini veya eylemlerini yanlış anlamak","e1":"Her silence was misconstrued as agreement.","e1t":"Sessizliği yanlışlıkla onay olarak yorumlandı.","e2":"Do not misconstrue my intentions.","e2t":"Niyetimi yanlış anlama."},{"w":"miscreant","tr":"alçak / suçlu / hain","te":"Noun","tt":"İsim","de":"A person who behaves badly or breaks the law (formal)","dt":"Kötü davranan veya yasayı çiğneyen kişi (resmi)","e1":"The police are looking for the miscreants.","e1t":"Polis o alçakları (suçluları) arıyor.","e2":"A young miscreant.","e2t":"Genç bir serseri (suçlu)."},{"w":"misdemeanor / misdemeanour","tr":"hafif suç / kabahat / kötü davranış","te":"Noun","tt":"İsim","de":"A crime that is not very serious; or a bad action","dt":"Çok ciddi olmayan suç; veya kötü eylem","e1":"Petty misdemeanors.","e1t":"Küçük kabahatler.","e2":"He was charged with a misdemeanor.","e2t":"Hafif bir suçla itham edildi."},{"w":"miserly","tr":"cimri / pinti / yetersiz (miktar)","te":"Adjective","tt":"Sıfat","de":"Not generous and unwilling to spend money; or very small","dt":"Cömert olmayan ve para harcamaya isteksiz; veya çok az","e1":"A miserly old man.","e1t":"Cimri yaşlı bir adam.","e2":"A miserly portion of food.","e2t":"Çok az (pinti işi) yemek porsiyonu."},{"w":"misgiving","tr":"endişe / kuşku / şüphe","te":"Noun","tt":"Isim","de":"A feeling of doubt or worry about a future event","dt":"Gelecekteki bir olay hakkında duyulan şüphe veya endişe","e1":"I have serious misgivings about the new project.","e1t":"Yeni proje hakkında ciddi endişelerim var.","e2":"Despite her misgivings, she agreed.","e2t":"Şüphelerine rağmen kabul etti."},{"w":"mishap","tr":"aksilik / talihsizlik / küçük kaza","te":"Noun","tt":"İsim","de":"An unlucky event or accident, usually a minor one","dt":"Genellikle küçük, şanssız bir olay veya kaza","e1":"A series of mishaps.","e1t":"Bir dizi aksilik.","e2":"The parade went off without a mishap.","e2t":"Tören bir aksilik çıkmadan tamamlandı."},{"w":"misnomer","tr":"yanlış isimlendirme / uygunsuz ad","te":"Noun","tt":"İsim","de":"A name that is inappropriate or wrong for something","dt":"Bir şey için uygun olmayan veya yanlış olan isim","e1":"\"Dry cleaning\" is a misnomer, as liquids are used.","e1t":"Sıvılar kullanıldığı için \"kuru temizleme\" yanlış bir isimlendirmedir.","e2":"It’s a bit of a misnomer to call it a luxury car.","e2t":"Ona lüks araba demek biraz yanlış olur (isimlendirme hatası)."},{"w":"misogynist","tr":"kadın düşmanı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who hates or dislikes women","dt":"Kadınlardan nefret eden veya onlardan hoşlanmayan kişi","e1":"He was accused of being a misogynist.","e1t":"Kadın düşmanı olmakla suçlandı.","e2":"Misogynistic comments.","e2t":"Kadın düşmanlığı içeren yorumlar."},{"w":"missive","tr":"resmi mektup / bildiri","te":"Noun","tt":"İsim","de":"A long or official letter (formal)","dt":"Uzun veya resmi mektup (resmi)","e1":"He received a missive from the headquarters.","e1t":"Karargahtan resmi bir mektup aldı.","e2":"To send an urgent missive.","e2t":"Acil bir bildiri göndermek."},{"w":"mnemonic","tr":"hafıza geliştirici / hatırlatıcı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A pattern or word used to help you remember something","dt":"Bir şeyi hatırlamanıza yardımcı olan desen veya kelime","e1":"A mnemonic device for the colors of the rainbow.","e1t":"Gökkuşağının renklerini hatırlatıcı yöntem.","e2":"\"Richard Of York Gave Battle In Vain\" is a mnemonic.","e2t":"(Gökkuşağı renkleri için) bir hatırlatıcıdır."},{"w":"mockery","tr":"alay / maskaralık / dalga geçme","te":"Noun","tt":"İsim","de":"The act of mocking someone or something; or a bad copy","dt":"Birini veya bir şeyi alaya alma; veya kötü bir taklit","e1":"He couldn't stand the mockery of his classmates.","e1t":"Sınıf arkadaşlarının alay etmesine dayanamadı.","e2":"The trial was a mockery of justice.","e2t":"Duruşma adaletin bir maskaralığıydı."},{"w":"modicum","tr":"az miktar / zerre / bir parça","te":"Noun","tt":"İsim","de":"A small amount of something good or pleasant","dt":"İyi veya hoş bir şeyin az miktarı","e1":"If you had a modicum of common sense...","e1t":"Eğer bir parça sağduyun olsaydı...","e2":"A modicum of truth.","e2t":"Bir zerre doğruluk."},{"w":"modish","tr":"modaya uygun / son moda / şık","te":"Adjective","tt":"Sıfat","de":"Fashionable or modern","dt":"Modaya uygun veya modern","e1":"A modish haircut.","e1t":"Modaya uygun bir saç kesimi.","e2":"Modish clothes.","e2t":"Şık (trend) kıyafetler."},{"w":"modulate","tr":"ayarlamak / değiştirmek (ses/frekans) / hafifletmek","te":"Verb","tt":"Fiil","de":"To change the style or loudness of something, especially your voice","dt":"Bir şeyin tarzını veya şiddetini (özellikle sesi) değiştirmek","e1":"He modulated his voice to sound more persuasive.","e1t":"Daha ikna edici görünmek için sesini ayarladı.","e2":"To modulate a radio signal.","e2t":"Bir radyo sinyalini modüle etmek."},{"w":"mogul","tr":"nüfuzlu kişi / patron / kral (sektörel)","te":"Noun","tt":"İsim","de":"A very rich and powerful person in business or film","dt":"İş veya film dünyasında çok zengin ve güçlü kişi","e1":"A movie mogul.","e1t":"Film kralı (dev yapımcı).","e2":"Property mogul.","e2t":"Emlak kralı."},{"w":"mollify","tr":"yatıştırmak / yumuşatmak / sakinleştirmek","te":"Verb","tt":"Fiil","de":"To make someone less angry or upset","dt":"Birini daha az öfkeli veya üzgün kılmak","e1":"The management tried to mollify the workers with a pay rise.","e1t":"Yönetim, işçileri maaş zammıyla yatıştırmaya çalıştı.","e2":"To mollify an angry crowd.","e2t":"Öfkeli bir kalabalığı sakinleştirmek."},{"w":"molt / moult","tr":"tüy dökmek / deri değiştirmek / tüy dökümü","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of an animal) to lose old feathers or skin to make way for new","dt":"(Hayvan için) yeniye yer açmak için eski tüy veya deriyi dökmek","e1":"Snakes molt their skin.","e1t":"Yılanlar deri değiştirir.","e2":"The birds are molting.","e2t":"Kuşlar tüy döküyor."},{"w":"momentous","tr":"çok önemli / tarihi / hayati","te":"Adjective","tt":"Sıfat","de":"Very important because of having a great influence on the future","dt":"Gelecek üzerinde büyük etkisi olduğu için çok önemli","e1":"A momentous decision.","e1t":"Hayati bir karar.","e2":"A momentous occasion.","e2t":"Tarihi (çok önemli) bir durum."},{"w":"monarchy","tr":"monarşi / krallık","te":"Noun","tt":"İsim","de":"A country that has a king or queen as its leader","dt":"Kral veya kraliçesi olan ülke","e1":"To abolish the monarchy.","e1t":"Monarşiyi kaldırmak.","e2":"Constitutional monarchy.","e2t":"Meşruti monarşi."},{"w":"monastic","tr":"manastır yaşamına ait / sade / çileci","te":"Adjective","tt":"Sıfat","de":"Relating to monks or nuns; or very simple and quiet","dt":"Rahiplerle ilgili; veya çok sade ve sessiz","e1":"Monastic life.","e1t":"Manastır hayatı.","e2":"A monastic cell.","e2t":"Manastır hücresi."},{"w":"monochromatic","tr":"tek renkli / monokrom","te":"Adjective","tt":"Sıfat","de":"Using only one color","dt":"Sadece tek bir renk kullanan","e1":"A monochromatic painting.","e1t":"Tek renkli tablo.","e2":"Monochromatic light.","e2t":"Tek renkli (tek dalga boylu) ışık."},{"w":"monolithic","tr":"tek parça / devasa ve sarsılmaz / monolitik","te":"Adjective","tt":"Sıfat","de":"Formed of a single large block of stone; or massive and unchanging","dt":"Tek bir büyük taş bloktan oluşmuş; veya devasa ve değişmez","e1":"A monolithic organization.","e1t":"Tek tip (değişmez/devasa) bir organizasyon.","e2":"Monolithic monuments.","e2t":"Tek parça taştan anıtlar."},{"w":"monotony","tr":"tekdüzelik / monotonluk / sıkıcılık","te":"Noun","tt":"İsim","de":"A lack of variation or change, causing boredom","dt":"Sıkıcılığa neden olan çeşitlilik veya değişim eksikliği","e1":"The monotony of factory work.","e1t":"Fabrika işinin tekdüzeliği.","e2":"To break the monotony.","e2t":"Monotonluğu kırmak."},{"w":"monumental","tr":"devasa / çok büyük / anıtsal / tarihi","te":"Adjective","tt":"Sıfat","de":"Very large, impressive, or important","dt":"Çok büyük, etkileyici veya önemli","e1":"A monumental achievement.","e1t":"Muazzam (tarihi) bir başarı.","e2":"A monumental waste of time.","e2t":"Devasa bir zaman kaybı."},{"w":"moodiness","tr":"karamsarlık / değişken ruh hali / huysuzluk","te":"Noun","tt":"İsim","de":"The quality of changing moods often and becoming unhappy","dt":"Ruh halinin sık sık değişmesi ve mutsuzlaşma niteliği","e1":"His moodiness makes him difficult to work with.","e1t":"Onun huysuzluğu (değişken ruh hali) onunla çalışmayı zorlaştırıyor.","e2":"Adolescent moodiness.","e2t":"Ergenlik karamsarlığı."},{"w":"moot","tr":"tartışmalı / karara bağlanmamış / tartışmaya açmak","te":"Adjective/Verb/Noun","tt":"Often discussed or argued about but having no definite answer","de":"Sık tartışılan ancak kesin cevabı olmayan","dt":"A moot point.","e1":"Tartışmalı (henüz netleşmemiş) nokta.","e1t":"The question is now moot (irrelevant).","e2":"Soru artık anlamsız (geçersiz).","e2t":""},{"w":"moralistic","tr":"ahlakçı / ahlak dersi veren","te":"Adjective","tt":"Sıfat","de":"Judging people's behavior based on your own ideas of right and wrong","dt":"Kendi doğru/yanlış fikirlerine dayanarak insanların davranışlarını yargılayan","e1":"A moralistic tone.","e1t":"Ahlakçı bir ton.","e2":"He can be very moralistic.","e2t":"Çok ahlakçı olabilir."},{"w":"moratorium","tr":"erteleme / durdurma / moratoryum","te":"Noun","tt":"İsim","de":"A temporary stopping of an activity, especially by official agreement","dt":"Bir faaliyetin, özellikle resmi anlaşmayla geçici olarak durdurulması","e1":"A moratorium on nuclear testing.","e1t":"Nükleer testlerin durdurulması (erteleme).","e2":"To call for a moratorium.","e2t":"Durdurma (erteleme) çağrısında bulunmak."},{"w":"mores","tr":"gelenekler / örf ve adetler / ahlaki kurallar","te":"Noun","tt":"İsim","de":"The traditional customs and ways of a particular group","dt":"Belirli bir grubun geleneksel adetleri ve yolları","e1":"Social mores.","e1t":"Sosyal gelenekler.","e2":"The mores of the Victorian era.","e2t":"Viktorya dönemi örf ve adetleri."},{"w":"moribund","tr":"ölmek üzere olan / can çekişen / durgun","te":"Adjective","tt":"Sıfat","de":"Especially of an organization or business, not active or successful","dt":"Özellikle kurum veya iş için; aktif veya başarılı olmayan","e1":"A moribund economy.","e1t":"Can çekişen (durgun) bir ekonomi.","e2":"The patient was moribund.","e2t":"Hasta ölmek üzereydi."},{"w":"morose","tr":"somurtkan / asık suratlı / karamsar","te":"Adjective","tt":"Sıfat","de":"Unhappy, annoyed, and unwilling to speak","dt":"Mutsuz, sinirli ve konuşmaya isteksiz","e1":"He sat in morose silence.","e1t":"Somurtkan bir sessizlik içinde oturdu.","e2":"A morose personality.","e2t":"Karamsar bir kişilik."},{"w":"mortify","tr":"utandırmak / rezil etmek / nefsini köreltmek","te":"Verb","tt":"Fiil","de":"To make someone feel very embarrassed","dt":"Birini çok utandırmak (yerin dibine sokmak)","e1":"I was mortified by my father's behavior.","e1t":"Babamın davranışından dolayı çok utandım.","e2":"To mortify the flesh (religious).","e2t":"Nefsi köreltmek (çile çekmek)."},{"w":"mosaic","tr":"mozaik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A pattern or picture made using many small pieces of colored stone","dt":"Renkli taş parçaları kullanılarak yapılan desen veya resim","e1":"A Roman mosaic.","e1t":"Roma mozaiği.","e2":"A mosaic of different cultures.","e2t":"Farklı kültürlerin mozaiği (karışımı)."},{"w":"motley","tr":"karışık / her telden / alacalı","te":"Adjective","tt":"Sıfat","de":"Consisting of many different types that do not seem to belong together","dt":"Birbiriyle ilgisiz görünen birçok farklı türden oluşan","e1":"A motley collection of furniture.","e1t":"Her telden (karışık) bir mobilya koleksiyonu.","e2":"A motley crew of sailors.","e2t":"Farklı tiplerden oluşan denizci tayfası."},{"w":"mottle","tr":"beneklemek / alacalamak / lekelemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To mark something with spots of different colors","dt":"Bir şeyi farklı renklerdeki beneklerle işaretlemek","e1":"Mottled skin.","e1t":"Benekli (alacalı) cilt.","e2":"A mottled green and brown surface.","e2t":"Yeşil ve kahverengi benekli bir yüzey."},{"w":"mould / mold","tr":"küf / kalıp / şekil vermek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A soft green or grey growth on old food; or a container to give shape","dt":"Eski gıdalardaki küf; veya şekil veren kap","e1":"The bread was covered in mould.","e1t":"Ekmek küfle kaplıydı.","e2":"To pour molten metal into a mould.","e2t":"Eriyiş metali bir kalıba dökmek."},{"w":"mountebank","tr":"şarlatan / dolandırıcı","te":"Noun","tt":"İsim","de":"A person who deceives people, especially in order to get money","dt":"İnsanları, özellikle para almak için aldatan kişi","e1":"He was a classic mountebank.","e1t":"Klasik bir şarlatandı.","e2":"(Not: Daha çok tarihi bir terimdir).","e2t":""},{"w":"muffle","tr":"sesi boğmak / örtmek / susturmak","te":"Verb","tt":"Fiil","de":"To make a sound quieter and less clear","dt":"Bir sesi daha sessiz ve daha az net hale getirmek","e1":"He tried to muffle his laughter.","e1t":"Gülüşünü boğmaya (bastırmaya) çalıştı.","e2":"The thick carpet muffled the sound of footsteps.","e2t":"Kalın halı ayak seslerini boğdu."},{"w":"mulish","tr":"inatçı / katır gibi","te":"Adjective","tt":"Sıfat","de":"Refusing to change your mind or help someone","dt":"Fikrini değiştirmeyi veya yardım etmeyi reddeden","e1":"A mulish refusal.","e1t":"İnatçı bir ret.","e2":"He can be very mulish at times.","e2t":"Bazen çok inatçı (katır gibi) olabilir."},{"w":"multifaceted","tr":"çok yönlü / çok boyutlu","te":"Adjective","tt":"Sıfat","de":"Having many different parts or features","dt":"Birçok farklı parçası veya özelliği olan","e1":"A multifaceted approach to the problem.","e1t":"Soruna çok yönlü bir yaklaşım.","e2":"She has a multifaceted personality.","e2t":"Çok yönlü bir kişiliği var."},{"w":"multifarious","tr":"çeşitli / çok çeşitli / türlü türlü","te":"Adjective","tt":"Sıfat","de":"Of many different types (formal)","dt":"Birçok farklı türden (resmi)","e1":"Multifarious activities.","e1t":"Çok çeşitli faaliyetler.","e2":"The multifarious functions of the brain.","e2t":"Beynin çok çeşitli işlevleri."},{"w":"multiplicity","tr":"çokluk / çeşitlilik","te":"Noun","tt":"İsim","de":"A large number or wide range of something","dt":"Bir şeyin büyük sayısı veya geniş yelpazesi","e1":"A multiplicity of choices.","e1t":"Seçenek çokluğu.","e2":"The multiplicity of factors involved.","e2t":"İşin içindeki etkenlerin çeşitliliği."},{"w":"munificent","tr":"eli açık / cömert / ihsanı bol","te":"Adjective","tt":"Sıfat","de":"Very generous with money (formal)","dt":"Para konusunda çok cömert (resmi)","e1":"A munificent gift.","e1t":"Cömertçe bir hediye.","e2":"The university received a munificent donation.","e2t":"Üniversite cömert bir bağış aldı."},{"w":"murky","tr":"bulanık / karanlık / şüpheli","te":"Adjective","tt":"Sıfat","de":"Dark and dirty; or (of a situation) suspicious","dt":"Karanlık ve kirli; veya (durum için) şüpheli","e1":"Murky waters.","e1t":"Bulanık sular.","e2":"A murky past.","e2t":"Karanlık (şüpheli) bir geçmiş."},{"w":"mutable","tr":"değişken / değişebilir","te":"Adjective","tt":"Sıfat","de":"Able or likely to change (formal)","dt":"Değişebilen veya değişmesi muhtemel (resmi)","e1":"Language is a mutable entity.","e1t":"Dil değişken bir varlıktır.","e2":"Mutable opinions.","e2t":"Değişken fikirler."},{"w":"mutilate","tr":"sakatlamak / bozmak / tahrif etmek","te":"Verb","tt":"Fiil","de":"To damage something severely, especially by removing a part","dt":"Bir şeyi, özellikle bir parçasını çıkararak ağır hasara uğratmak","e1":"The body had been badly mutilated.","e1t":"Ceset feci şekilde tahrif edilmişti (parçalanmıştı).","e2":"To mutilate a statue.","e2t":"Bir heykeli bozmak (parçalamak)."},{"w":"mutinous","tr":"isyankar / asi","te":"Adjective","tt":"Sıfat","de":"Refusing to obey orders, especially in the military","dt":"Özellikle askeri alanda emirlere uymayı reddeden","e1":"The sailors became mutinous.","e1t":"Denizciler isyan bayrağını çekti (asileşti).","e2":"A mutinous look.","e2t":"İsyankar bir bakış."},{"w":"myopic","tr":"uzağı göremeyen / miyop / dar görüşlü","te":"Adjective","tt":"Sıfat","de":"Unable to see things clearly from a distance; or lacking foresight","dt":"Uzaktaki şeyleri net göremeyen; veya ileriyi göremeyen","e1":"Myopic vision.","e1t":"Miyop görüş.","e2":"A myopic foreign policy.","e2t":"Dar görüşlü (ileriyi göremeyen) bir dış politika."},{"w":"myriad","tr":"sayısız / çok büyük miktar","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A very large number of something","dt":"Bir şeyin çok büyük sayısı","e1":"A myriad of possibilities.","e1t":"Sayısız olasılık.","e2":"The myriad stars in the sky.","e2t":"Gökyüzündeki sayısız yıldız."},{"w":"mystify","tr":"şaşırtmak / kafasını karıştırmak / muammaya dönüştürmek","te":"Verb","tt":"Fiil","de":"To confuse someone by being impossible to understand","dt":"Anlaşılması imkansız olarak birinin kafasını karıştırmak","e1":"Her disappearance mystified the police.","e1t":"Onun ortadan kaybolması polisi şaşırttı (muammada bıraktı).","e2":"I was mystified by his behavior.","e2t":"Davranışı karşısında şaşkına döndüm."},{"w":"nadir","tr":"en alt nokta / dibe vuruş","te":"Noun","tt":"İsim","de":"The worst or lowest point of something","dt":"Bir şeyin en kötü veya en düşük noktası","e1":"The nadir of his career.","e1t":"Kariyerinin en alt noktası (dibe vuruşu).","e2":"Relationships between the two countries reached a nadir.","e2t":"İki ülke arasındaki ilişkiler en düşük seviyeye ulaştı."},{"w":"nag","tr":"dırdır etmek / kafasına kakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To annoy someone by complaining constantly","dt":"Sürekli şikayet ederek birini rahatsız etmek","e1":"Stop nagging me about the housework!","e1t":"Ev işleri hakkında bana dırdır etmeyi bırak!","e2":"A nagging pain.","e2t":"Sürekli (dinmeyen) bir ağrı."},{"w":"naivete / naïveté","tr":"saflık / toytoy / deneyimsizlik","te":"Noun","tt":"İsim","de":"Lack of experience, wisdom, or judgment","dt":"Deneyim, bilgelik veya muhakeme eksikliği","e1":"Political naivete.","e1t":"Siyasi saflık (deneyimsizlik).","e2":"He displayed an amazing naivete.","e2t":"Şaşırtıcı bir saflık sergiledi."},{"w":"narcissist","tr":"narsist / kendine aşık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has an excessive interest in or admiration of themselves","dt":"Kendisine aşırı ilgi veya hayranlık duyan kişi","e1":"He is a complete narcissist.","e1t":"O tam bir narsisttir.","e2":"Narcissistic personality disorder.","e2t":"Narsistik kişilik bozukluğu."},{"w":"nascent","tr":"doğmakta olan / yeni başlayan / henüz gelişen","te":"Adjective","tt":"Sıfat","de":"Only recently at the beginning of its existence","dt":"Varlığının henüz çok başında olan","e1":"A nascent democracy.","e1t":"Yeni filizlenen bir demokrasi.","e2":"The nascent space industry.","e2t":"Doğmakta olan uzay endüstrisi."},{"w":"nauseate","tr":"midesini bulandırmak / iğrendirmek","te":"Verb","tt":"Fiil","de":"To make someone feel as if they are going to vomit","dt":"Birinin midesini bulandırmak veya iğrenmesine neden olmak","e1":"The smell of rotting meat nauseates me.","e1t":"Çürümüş et kokusu midemi bulandırıyor.","e2":"I was nauseated by the violence.","e2t":"Şiddetten iğrendim."},{"w":"nautical","tr":"denizcilikle ilgili / bahri","te":"Adjective","tt":"Sıfat","de":"Relating to ships, sailors, or sailing","dt":"Gemiler, denizciler veya denizcilikle ilgili","e1":"Nautical miles.","e1t":"Deniz mili.","e2":"Nautical equipment.","e2t":"Denizcilik ekipmanları."},{"w":"navigable","tr":"gemi işleyebilir / ulaşıma açık (su yolu)","te":"Adjective","tt":"Sıfat","de":"(Of a river or road) deep or wide enough for ships","dt":"(Nehir/yol için) gemilerin geçebileceği kadar derin veya geniş","e1":"A navigable river.","e1t":"Ulaşıma açık (gemi işleyebilir) nehir.","e2":"Is the canal navigable?","e2t":"Kanal ulaşıma elverişli mi?"},{"w":"necromancy","tr":"büyücülük / ölülerle konuşma","te":"Noun","tt":"İsim","de":"The practice of talking to the spirits of dead people","dt":"Ölülerin ruhlarıyla konuşma pratiği","e1":"He was accused of practicing necromancy.","e1t":"Büyücülük yapmakla suçlandı.","e2":"Ancient necromancy.","e2t":"Kadim büyücülük."},{"w":"nefarious","tr":"kötü şöhretli / alçakça / haince","te":"Adjective","tt":"Sıfat","de":"Morally bad; wicked (formal)","dt":"Ahlaken kötü; haince (resmi)","e1":"Nefarious activities.","e1t":"Haince faaliyetler.","e2":"A nefarious scheme to steal money.","e2t":"Para çalmak için yapılmış alçakça bir plan."},{"w":"nemesis","tr":"kaçınılmaz ceza / ezeli düşman / bela","te":"Noun","tt":"İsim","de":"Someone or something that causes major problems or defeat","dt":"Büyük sorunlara veya yenilgiye neden olan kişi veya şey","e1":"He finally met his nemesis.","e1t":"Sonunda dengini (belasını) buldu.","e2":"Logic is the nemesis of superstition.","e2t":"Mantık, batıl inancın ezeli düşmanıdır."},{"w":"neologism","tr":"yeni türetilmiş sözcük / yeni terim","te":"Noun","tt":"İsim","de":"A new word or a new meaning for an established word","dt":"Yeni bir kelime veya yerleşik bir kelimeye verilen yeni anlam","e1":"Technical neologisms.","e1t":"Teknik yeni terimler.","e2":"\"Selfie\" was once a neologism.","e2t":"\"Selfie\" bir zamanlar yeni türetilmiş bir sözcüktü."},{"w":"neophyte","tr":"acemi / yeni başlayan / yeni girmiş (din/grup)","te":"Noun","tt":"İsim","de":"A person who is new to a subject, skill, or belief","dt":"Bir konuya, beceriye veya inanca yeni başlamış kişi","e1":"A neophyte in the world of politics.","e1t":"Siyaset dünyasında bir acemi.","e2":"Neophytes in the monastery.","e2t":"Manastırdaki çömezler."},{"w":"nepotism","tr":"adam kayırma / eş dost kayırmacılığı","te":"Noun","tt":"İsim","de":"Using your power to get good jobs for your family","dt":"Ailesine iyi işler sağlamak için gücünü kullanma","e1":"He was accused of nepotism when he hired his son.","e1t":"Oğlunu işe aldığında adam kayırmakla suçlandı.","e2":"To fight against nepotism.","e2t":"Kayırmacılığa karşı savaşmak."},{"w":"nettle","tr":"kızdırmak / sinirlendirmek / ısırgan otu","te":"Verb/Noun","tt":"Fiil/İsim","de":"To annoy someone; or a wild plant with stinging hairs","dt":"Birini kızdırmak; veya ısırgan otu","e1":"She was nettled by his rude remark.","e1t":"Onun kaba sözüne sinirlendi.","e2":"To be stung by a nettle.","e2t":"Isırgan otu tarafından dalanmak."},{"w":"nexus","tr":"bağlantı / merkez / odak noktası","te":"Noun","tt":"İsim","de":"An important connection between the parts of a system","dt":"Bir sistemin parçaları arasındaki önemli bağlantı","e1":"The nexus between health and diet.","e1t":"Sağlık ve diyet arasındaki bağlantı.","e2":"A nexus of global trade.","e2t":"Küresel ticaretin merkezi (odak noktası)."},{"w":"nicety","tr":"incelik / ayrıntı / titizlik","te":"Noun","tt":"İsim","de":"A small detail or a fine point; or good behavior","dt":"Küçük bir detay veya ince bir nokta; veya nazik davranış","e1":"The niceties of social etiquette.","e1t":"Sosyal görgü kurallarının incelikleri.","e2":"To observe the legal niceties.","e2t":"Hukuki ayrıntılara uymak."},{"w":"niggardly","tr":"cimri / pinti / çok az (miktar)","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not generous; or very small in amount","dt":"Cömert olmayan; veya miktar olarak çok az","e1":"A niggardly salary increase.","e1t":"Çok az (pinti işi) maaş artışı.","e2":"Niggardly with praise.","e2t":"Övgü konusunda pinti."},{"w":"niggle","tr":"önemsiz şeylerle uğraşmak / içine dert olmak / dırdır","te":"Verb/Noun","tt":"Fiil/İsim","de":"To worry someone slightly; or to criticize small details","dt":"Birini hafifçe endişelendirmek; veya küçük detayları eleştirmek","e1":"A niggling doubt.","e1t":"İçini kemiren (aklına takılan) bir şüphe.","e2":"Stop niggling about the cost.","e2t":"Maliyet hakkında dırdır etmeyi (ufak tefek şeylere takılmayı) bırak."},{"w":"nihilist","tr":"hiççi / nihilist","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who believes that life is meaningless","dt":"Hayatın anlamsız olduğuna inanan kişi","e1":"A nihilist philosophy.","e1t":"Nihilist felsefe.","e2":"He has a nihilist approach to art.","e2t":"Sanata karşı hiççi bir yaklaşımı var."},{"w":"nirvana","tr":"huzur / nirvana / en üst aşama","te":"Noun","tt":"İsim","de":"A state of perfect happiness and peace","dt":"Tam bir mutluluk ve huzur hali","e1":"To reach nirvana.","e1t":"Nirvana'ya ulaşmak.","e2":"This beach is a real nirvana.","e2t":"Bu plaj gerçek bir huzur köşesi."},{"w":"noisome","tr":"pis kokulu / zararlı / nahoş","te":"Adjective","tt":"Sıfat","de":"Having an extremely unpleasant smell; or harmful","dt":"Son derece kötü kokan; veya zararlı","e1":"Noisome smells from the sewer.","e1t":"Kanalizasyondan gelen pis kokular.","e2":"Noisome vapors.","e2t":"Zararlı buharlar."},{"w":"nomadic","tr":"göçebe / gezgin","te":"Adjective","tt":"Sıfat","de":"Moving from one place to another rather than living in one place","dt":"Bir yerde yaşamak yerine bir yerden başka yere giden","e1":"Nomadic tribes.","e1t":"Göçebe kabileler.","e2":"A nomadic lifestyle.","e2t":"Göçebe bir yaşam tarzı."},{"w":"nonentity","tr":"önemsiz kişi / varlığı yokluğu bir","te":"Noun","tt":"İsim","de":"A person without any special qualities or importance","dt":"Hiçbir özel niteliği veya önemi olmayan kişi","e1":"He was a total nonentity before he won the lottery.","e1t":"Piyangoyu kazanmadan önce adı sanı duyulmamış (etkisiz) biriydi.","e2":"To treat someone as a nonentity.","e2t":"Birine yokmuş gibi davranmak."},{"w":"nonplus","tr":"şaşırtmak / dilsiz bırakmak / apıştırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To surprise someone so much that they do not know what to do","dt":"Birini ne yapacağını bilemeyecek kadar şaşırtmak","e1":"I was completely nonplussed by his question.","e1t":"Sorusu karşısında tamamen apışıp kaldım.","e2":"He seemed nonplussed for a moment.","e2t":"Bir an için şaşkınlık yaşadı."},{"w":"notoriety","tr":"kötü şöhret / adı çıkmışlık","te":"Noun","tt":"İsim","de":"The state of being famous for something bad","dt":"Kötü bir şeyle ünlü olma durumu","e1":"He achieved notoriety as a bank robber.","e1t":"Banka soyguncusu olarak kötü bir şöhret kazandı.","e2":"Notoriety for his violent temper.","e2t":"Sert mizacıyla nam salmışlık."},{"w":"noxious","tr":"zararlı / zehirli","te":"Adjective","tt":"Sıfat","de":"Poisonous or very harmful","dt":"Zehirli veya çok zararlı","e1":"Noxious fumes.","e1t":"Zehirli gazlar (dumanlar).","e2":"Noxious weeds.","e2t":"Zararlı otlar."},{"w":"nub","tr":"esas nokta / kilit nokta / küçük parça","te":"Noun","tt":"İsim","de":"The most important or basic part of something","dt":"Bir şeyin en önemli veya temel parçası","e1":"The nub of the problem.","e1t":"Sorunun kilit noktası.","e2":"Now we come to the nub of the matter.","e2t":"Şimdi meselenin özüne geliyoruz."},{"w":"numerology","tr":"sayı bilimi / nümeroloji","te":"Noun","tt":"İsim","de":"The study of the magical power of numbers","dt":"Sayıların sihirli gücünün incelenmesi","e1":"She has an interest in numerology.","e1t":"Nümerolojiye ilgisi var.","e2":"To use numerology to predict the future.","e2t":"Geleceği tahmin etmek için sayı bilimini kullanmak."},{"w":"nuptial","tr":"düğünle ilgili / izdivaç","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to marriage or a wedding ceremony","dt":"Evlilik veya düğün töreniyle ilgili","e1":"Nuptial vows.","e1t":"Evlilik yeminleri.","e2":"Pre","e2t":"nuptial agreement."},{"w":"oaf","tr":"şapşal / kaba ve aptal adam","te":"Noun","tt":"İsim","de":"A stupid, rude, or awkward person (especially a man)","dt":"Aptal, kaba veya beceriksiz kişi","e1":"A clumsy oaf.","e1t":"Sakar şapşal.","e2":"He is a big, friendly oaf.","e2t":"O, iri yarı, dost canlısı bir şapşaldır."},{"w":"obdurate","tr":"inatçı / tavizsiz / taş kalpli","te":"Adjective","tt":"Sıfat","de":"Refusing to change your mind or your actions","dt":"Fikrini veya eylemlerini değiştirmeyi reddeden","e1":"An obdurate refusal to cooperate.","e1t":"İş birliği yapmama konusundaki inatçı ret.","e2":"He remained obdurate in his decision.","e2t":"Kararında tavizsiz kaldı."},{"w":"obelisk","tr":"dikilitaş / obelisk","te":"Noun","tt":"İsim","de":"A tall, thin, four","dt":"sided stone monument","e1":"Uzun, ince, dört kenarlı taş anıt","e1t":"The Egyptian obelisk.","e2":"Mısır dikilitaşı.","e2t":"A granite obelisk."},{"w":"obfuscate","tr":"kafa karıştırmak / bulandırmak / anlaşılmaz kılmak","te":"Verb","tt":"Fiil","de":"To make something less clear and harder to understand","dt":"Bir şeyi daha az net ve anlaşılması daha zor hale getirmek","e1":"To obfuscate the issue.","e1t":"Konuyu bulandırmak (kafa karıştırmak).","e2":"Legal language is often used to obfuscate the truth.","e2t":"Hukuk dili genellikle gerçeği gizlemek/anlaşılmaz kılmak için kullanılır."},{"w":"obituary","tr":"ölüm ilanı / nekroloji","te":"Noun","tt":"İsim","de":"A report in a newspaper that announces someone's death","dt":"Bir gazetedeki ölüm haberi/yazısı","e1":"To read the obituaries.","e1t":"Ölüm ilanlarını okumak.","e2":"An obituary for a famous writer.","e2t":"Ünlü bir yazar için yazılmış nekroloji yazısı."},{"w":"oblivion","tr":"unutulmuşluk / silinme / bilinçsizlik hali","te":"Noun","tt":"İsim","de":"The state of being completely forgotten; or being unconscious","dt":"Tamamen unutulma durumu; veya bilinçsizlik","e1":"The book has faded into oblivion.","e1t":"Kitap unutulup gitti (tarihe karıştı).","e2":"He drank himself into oblivion.","e2t":"Kendinden geçene (bilincini yitirene) kadar içti."},{"w":"obloquy","tr":"iftira / kötüleme / rezalet","te":"Noun","tt":"Isim","de":"Strong public criticism or loss of respect (formal)","dt":"Güçlü halk eleştirisi veya itibar kaybı (resmi)","e1":"To suffer the obloquy of one's peers.","e1t":"Akranlarının kötülemesine maruz kalmak.","e2":"A life of obloquy.","e2t":"Rezalet/aşağılanma dolu bir hayat."},{"w":"obnoxious","tr":"iğrenç / çok itici / nahoş","te":"Adjective","tt":"Sıfat","de":"Very unpleasant or rude","dt":"Çok nahoş veya kaba","e1":"Obnoxious behavior.","e1t":"İtici (nahoş) davranış.","e2":"An obnoxious smell.","e2t":"İğrenç bir koku."},{"w":"obsequious","tr":"dalkavuk / yaltakçı / aşırı saygılı","te":"Adjective","tt":"Sıfat","de":"Too eager to praise or obey someone","dt":"Birine övgü yağdırmaya veya itaat etmeye aşırı istekli","e1":"An obsequious shop assistant.","e1t":"Dalkavukça davranan (yaltakçı) bir tezgahtar.","e2":"He was served by obsequious waiters.","e2t":"Ona yaltakçı garsonlar hizmet etti."},{"w":"observance","tr":"uyma (kurala) / riayet / kutlama","te":"Noun","tt":"İsim","de":"The act of obeying a law or custom; or a religious ceremony","dt":"Bir kanuna/geleneğe uyma; veya dini tören","e1":"Strict observance of the rules.","e1t":"Kurallara sıkı sıkıya riayet (uyma).","e2":"Religious observances.","e2t":"Dini vecibeler (törenler)."},{"w":"obsessive","tr":"takıntılı / saplantılı","te":"Adjective","tt":"Sıfat","de":"Thinking about something all the time in a way that is not normal","dt":"Bir şeyi normal olmayan bir şekilde sürekli düşünen","e1":"He is obsessive about cleanliness.","e1t":"Temizlik konusunda takıntılıdır.","e2":"An obsessive interest in details.","e2t":"Detaylara yönelik saplantılı bir ilgi."},{"w":"obstetrician","tr":"doğum uzmanı","te":"Noun","tt":"İsim","de":"A doctor who has special training in helping women give birth","dt":"Doğum konusunda uzmanlaşmış doktor","e1":"She decided to see an obstetrician.","e1t":"Bir doğum uzmanına görünmeye karar verdi.","e2":"A leading obstetrician.","e2t":"Önde gelen bir doğum uzmanı."},{"w":"obstreperous","tr":"gürültücü / hırçın / ele avuca sığmaz","te":"Adjective","tt":"Sıfat","de":"Difficult to manage and noisy","dt":"Yönetilmesi zor ve gürültülü","e1":"An obstreperous child.","e1t":"Hırçın ve gürültücü bir çocuk.","e2":"Obstreperous customers.","e2t":"Sorun çıkaran (gürültücü) müşteriler."},{"w":"obtuse","tr":"kıt anlayışlı / kalın kafalı / geniş (açı)","te":"Adjective","tt":"Sıfat","de":"Stupid and slow to understand; or (of an angle) more than 90 degrees","dt":"Anlaması yavaş ve aptalca; veya (açı için) 90 dereceden büyük","e1":"Are you being intentionally obtuse?","e1t":"Kasten mi anlamamazlıktan geliyorsun (kıt anlayışlı davranıyorsun)?","e2":"An obtuse angle.","e2t":"Geniş açı."},{"w":"obviate","tr":"gereksiz kılmak / ortadan kaldırmak / önlemek","te":"Verb","tt":"Fiil","de":"To remove a difficulty or the need for something","dt":"Bir zorluğu veya ihtiyacı ortadan kaldırmak","e1":"The new medical treatment obviates the need for surgery.","e1t":"Yeni tedavi ameliyat ihtiyacını ortadan kaldırıyor (gereksiz kılıyor).","e2":"To obviate a risk.","e2t":"Bir riski önlemek."},{"w":"occident","tr":"batı / batı dünyası","te":"Noun","tt":"İsim","de":"The western part of the world (formal)","dt":"Dünyanın batı kısmı (resmi)","e1":"The cultures of the Orient and the Occident.","e1t":"Doğu ve Batı kültürleri.","e2":"(Not: 'Orient' kelimesinin zıttıdır).","e2t":""},{"w":"occlude","tr":"tıkamak / kapatmak / engel olmak","te":"Verb","tt":"Fiil","de":"To block or close an opening or passage","dt":"Bir açıklığı veya geçidi tıkamak/kapatmak","e1":"A blood clot can occlude a major artery.","e1t":"Bir kan pıhtısı ana arteri tıkayabilir.","e2":"Occluded front (meteorology).","e2t":"Kapalı cephe."},{"w":"occult","tr":"gizli güçler / doğaüstü / gizemli","te":"Adjective/Noun/Verb","tt":"Relating to magical or supernatural powers","de":"Büyülü veya doğaüstü güçlerle ilgili","dt":"An interest in the occult.","e1":"Gizemli güçlere (okültizme) duyulan ilgi.","e1t":"Occult practices.","e2":"Doğaüstü uygulamalar.","e2t":""},{"w":"ocular","tr":"göze ait / görsel","te":"Adjective","tt":"Sıfat","de":"Relating to the eye or the ability to see","dt":"Gözle veya görme yetisiyle ilgili","e1":"Ocular muscles.","e1t":"Göz kasları.","e2":"An ocular examination.","e2t":"Göz muayenesi."},{"w":"odious","tr":"iğrenç / tiksindirici / nefret uyandırıcı","te":"Adjective","tt":"Sıfat","de":"Extremely unpleasant; causing hate","dt":"Son derece nahoş; nefret uyandıran","e1":"An odious crime.","e1t":"İğrenç bir suç.","e2":"What an odious man!","e2t":"Ne kadar iğrenç (itici) bir adam!"},{"w":"odium","tr":"nefret / tiksinti / rezalet","te":"Noun","tt":"İsim","de":"Hate and strong disapproval (formal)","dt":"Nefret ve güçlü onaylamama (resmi)","e1":"He incurred the odium of everyone.","e1t":"Herkesin nefretini üzerine çekti.","e2":"To live in odium.","e2t":"Nefret/rezalet içinde yaşamak."},{"w":"odoriferous","tr":"kokulu / koku yayan","te":"Adjective","tt":"Sıfat","de":"Having a strong smell (formal)","dt":"Güçlü bir kokusu olan (resmi)","e1":"Odoriferous plants.","e1t":"Koku yayan bitkiler.","e2":"An odoriferous mixture.","e2t":"Kokulu bir karışım."},{"w":"odorous","tr":"kokulu / keskin kokulu","te":"Adjective","tt":"Sıfat","de":"Having a smell, especially an unpleasant one","dt":"Kokusu olan, özellikle nahoş kokan","e1":"Odorous chemicals.","e1t":"Keskin kokulu kimyasallar.","e2":"An odorous gas.","e2t":"Kokulu bir gaz."},{"w":"odyssey","tr":"uzun yolculuk / macera dolu serüven","te":"Noun","tt":"İsim","de":"A long and exciting journey of discovery","dt":"Uzun ve heyecan verici keşif yolculuğu","e1":"His spiritual odyssey.","e1t":"Onun ruhani yolculuğu (serüveni).","e2":"A ten","e2t":"year odyssey through Asia."},{"w":"offhand","tr":"hazırlıksız / üstünkörü / ilgisiz","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Without thinking or preparing; or unfriendly","dt":"Düşünmeden veya hazırlanmadan; veya ilgisiz/kaba","e1":"I didn't mean to be offhand with you.","e1t":"Sana karşı ilgisiz (kaba) davranmak istememiştim.","e2":"I can't tell you the exact figure offhand.","e2t":"Şu an (hazırlıksız) size tam rakamı söyleyemem."},{"w":"officious","tr":"işgüzar / her şeye burnunu sokan / memur tavırlı","te":"Adjective","tt":"Sıfat","de":"Too eager to tell people what to do","dt":"İnsanlara ne yapacağını söylemeye çok meraklı (işgüzar)","e1":"An officious ticket inspector.","e1t":"İşgüzar bir bilet kontrolörü.","e2":"He’s an officious little man.","e2t":"O, her şeye karışan işgüzar bir adamdır."},{"w":"ogle","tr":"bakış atmak / göz süzmek / cinsel arzuyla bakmak","te":"Verb","tt":"Fiil","de":"To look at someone in a way that shows sexual interest","dt":"Birine cinsel ilgi gösteren bir şekilde bakmak","e1":"He was ogling the women at the bar.","e1t":"Bardaki kadınlara göz süzüyordu (bakıyordu).","e2":"Stop ogling me!","e2t":"Bana öyle bakmayı kes!"},{"w":"olfactory","tr":"koku alma duyusuyla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the sense of smell","dt":"Koku alma duyusuyla ilgili","e1":"The olfactory nerve.","e1t":"Koku alma siniri.","e2":"Olfactory organs.","e2t":"Koku alma organları."},{"w":"oligarchy","tr":"oligarşi / azınlık yönetimi","te":"Noun","tt":"İsim","de":"A government or country that is controlled by a small group","dt":"Küçük bir grup tarafından yönetilen hükümet veya ülke","e1":"To live under an oligarchy.","e1t":"Bir oligarşi altında yaşamak.","e2":"The ruling oligarchy.","e2t":"Yönetici azınlık."},{"w":"omni","tr":"her şey / tüm","te":"Prefix","tt":"Ön ek","de":"All; in all ways","dt":"Her şey; her yönden","e1":"Omnivore (eats everything).","e1t":"Hepçil.","e2":"Omnidirectional (all directions).","e2t":"Her yöne (yönlü)."},{"w":"omnipresent","tr":"her yerde olan","te":"Adjective","tt":"Sıfat","de":"Present everywhere at the same time","dt":"Aynı anda her yerde bulunan","e1":"The omnipresent threat of war.","e1t":"Her an her yerde hissedilen savaş tehdidi.","e2":"God is believed to be omnipresent.","e2t":"Tanrı'nın her yerde olduğuna inanılır."},{"w":"omniscient","tr":"her şeyi bilen","te":"Adjective","tt":"Sıfat","de":"Knowing everything","dt":"Her şeyi bilen","e1":"An omniscient narrator.","e1t":"Her şeyi bilen (ilahi) anlatıcı.","e2":"To believe in an omniscient God.","e2t":"Her şeyi bilen bir Tanrı'ya inanmak."},{"w":"omnivorous","tr":"hepçil / her şeyi yiyen","te":"Adjective","tt":"Sıfat","de":"Eating both plants and animals; or interested in everything","dt":"Hem bitki hem hayvan yiyen; veya her şeye ilgi duyan","e1":"Rats are omnivorous.","e1t":"Fareler hepçildir.","e2":"An omnivorous reader.","e2t":"Her şeyi (ne bulsa) okuyan bir okuyucu."},{"w":"onerous","tr":"zahmetli / ağır / yük getiren","te":"Adjective","tt":"Sıfat","de":"Needing great effort; causing difficulty (formal)","dt":"Büyük çaba gerektiren; zorluk çıkaran (resmi)","e1":"An onerous task.","e1t":"Zahmetli bir görev.","e2":"Onerous regulations.","e2t":"Ağır (yük getiren) düzenlemeler."},{"w":"onslaught","tr":"şiddetli saldırı / hücum","te":"Noun","tt":"İsim","de":"A very powerful attack","dt":"Çok güçlü saldırı","e1":"A fierce onslaught by the enemy.","e1t":"Düşmanın şiddetli saldırısı.","e2":"An onslaught of questions.","e2t":"Soru yağmuru (saldırısı)."},{"w":"opalescent","tr":"yanardöner / opalimsi / sedefli","te":"Adjective","tt":"Sıfat","de":"Showing varying colors like an opal","dt":"Opal gibi değişen renkler gösteren","e1":"Opalescent glass.","e1t":"Yanardöner cam.","e2":"The opalescent surface of the water.","e2t":"Suyun yanardöner (sedefli) yüzeyi."},{"w":"opiate","tr":"uyuşturucu / sakinleştirici","te":"Noun","tt":"İsim","de":"A drug that contains opium and reduces pain","dt":"Afyon içeren ve ağrıyı azaltan ilaç/uyuşturucu","e1":"Natural opiates.","e1t":"Doğal uyuşturucular.","e2":"To be addicted to opiates.","e2t":"Uyuşturucu (opiyat) bağımlısı olmak."},{"w":"opportunist","tr":"fırsatçı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who takes advantage of chances without thinking of morals","dt":"Ahlaki kuralları düşünmeden fırsatları değerlendiren kişi","e1":"He is a political opportunist.","e1t":"O, siyasi bir fırsatçıdır.","e2":"An opportunist crime.","e2t":"Fırsatçılık (açıkgözlük) eseri bir suç."},{"w":"opprobrium","tr":"aşağılama / rüsvaylık / kınama","te":"Noun","tt":"Isim","de":"Severe criticism and blame (formal)","dt":"Şiddetli eleştiri ve suçlama (resmi)","e1":"To suffer the opprobrium of the public.","e1t":"Halkın kınamasına (aşağılamasına) maruz kalmak.","e2":"International opprobrium.","e2t":"Uluslararası kınama."},{"w":"optician","tr":"gözlükçü / optisyen","te":"Noun","tt":"İsim","de":"A person who examines eyes and sells glasses","dt":"Göz muayenesi yapan ve gözlük satan kişi","e1":"To visit the optician.","e1t":"Gözlükçüye gitmek.","e2":"Dispensing optician.","e2t":"Reçeteli gözlük hazırlayan optisyen."},{"w":"optimist","tr":"iyimser","te":"Noun","tt":"İsim","de":"A person who always expects good things to happen","dt":"Her zaman iyi şeyler olmasını bekleyen kişi","e1":"He is a natural optimist.","e1t":"O doğuştan iyimserdir.","e2":"An incurable optimist.","e2t":"İflah olmaz bir iyimser."},{"w":"optimum","tr":"en uygun / en iyi / en verimli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Best; most likely to bring success","dt":"En iyi; başarı getirmesi en muhtemel olan","e1":"The optimum temperature for growth.","e1t":"Büyüme için en uygun sıcaklık.","e2":"To achieve the optimum results.","e2t":"En verimli sonuçları elde etmek."},{"w":"opulence","tr":"zenginlik / lüks / görkem","te":"Noun","tt":"İsim","de":"The quality of being expensive and luxurious","dt":"Pahalı ve lüks olma niteliği","e1":"The opulence of the hotel.","e1t":"Otelin görkemi (lüksü).","e2":"To live in opulence.","e2t":"Zenginlik içinde yaşamak."},{"w":"opus","tr":"eser / yapıt (özellikle müzik)","te":"Noun","tt":"İsim","de":"A piece of work, especially a musical composition","dt":"Bir çalışma, özellikle müzikal beste","e1":"Beethoven's Opus 131.","e1t":"Beethoven'ın 131. eseri.","e2":"Magnum opus (greatest work).","e2t":"Başyapıt."},{"w":"oracular","tr":"kehanet gibi / gizemli / kesin","te":"Adjective","tt":"Sıfat","de":"Mysterious and suggesting that you know the future","dt":"Geleceği bildiğini düşündüren ve gizemli","e1":"Oracular statements.","e1t":"Kehanet gibi (gizemli) beyanlar.","e2":"An oracular voice.","e2t":"Tanrısal (kesin) bir ses tonu."},{"w":"orator","tr":"hatip / güzel konuşan kişi","te":"Noun","tt":"İsim","de":"A person who makes formal speeches in public","dt":"Topluluk önünde resmi konuşmalar yapan kişi","e1":"A brilliant orator.","e1t":"Harika bir hatip.","e2":"Political orators.","e2t":"Siyasi hatipler."},{"w":"ordain","tr":"emretmek / atamak (din adamı) / kadere yazmak","te":"Verb","tt":"Fiil","de":"To officially make someone a priest; or to order officially","dt":"Birini resmen rahip yapmak; veya resmen emretmek","e1":"He was ordained as a priest.","e1t":"Rahip olarak atandı.","e2":"It was ordained by law.","e2t":"Kanunla emredildi (belirlendi)."},{"w":"ordinance","tr":"yönetmelik / kararname / kural","te":"Noun","tt":"İsim","de":"An official order or rule made by a government (formal)","dt":"Hükümet tarafından yapılan resmi emir veya kural","e1":"A local ordinance.","e1t":"Yerel yönetmelik.","e2":"Under a city ordinance.","e2t":"Bir şehir kararnamesi uyarınca."},{"w":"ordination","tr":"atama / takdis (din adamı)","te":"Noun","tt":"İsim","de":"The ceremony of making someone a priest","dt":"Birini rahip yapma töreni","e1":"The ordination of women.","e1t":"Kadınların din görevlisi olarak atanması.","e2":"An ordination ceremony.","e2t":"Takdis töreni."},{"w":"orgy","tr":"alem / cümbüş / aşırılık","te":"Noun","tt":"İsim","de":"A party with a lot of eating, drinking, and sex; or too much of something","dt":"Çok yeme","e1":"içme ve cinsellik olan parti; veya bir şeyin aşırılığı","e1t":"An orgy of violence.","e2":"Şiddet cümbüşü (aşırılığı).","e2t":"Drunken orgies."},{"w":"orifice","tr":"delik / açıklık / ağız","te":"Noun","tt":"İsim","de":"An opening or a hole, especially in the body","dt":"Özellikle vücuttaki bir açıklık veya delik","e1":"A nasal orifice.","e1t":"Burun deliği.","e2":"The orifice of the pipe.","e2t":"Borunun ağzı (açıklığı)."},{"w":"ornate","tr":"süslü / şatafatlı / ağdalı","te":"Adjective","tt":"Sıfat","de":"Having a lot of complex decoration; or (of writing) using many difficult words","dt":"Çok fazla karmaşık süslemesi olan; veya (yazı için) çok süslü","e1":"Ornate furniture.","e1t":"Şatafatlı mobilya.","e2":"An ornate gold mirror.","e2t":"Süslü altın bir ayna."},{"w":"ornithologist","tr":"kuş bilimci / ornitolog","te":"Noun","tt":"İsim","de":"A person who studies birds","dt":"Kuşları inceleyen kişi","e1":"A world","e1t":"famous ornithologist.","e2":"Dünyaca ünlü bir kuş bilimci.","e2t":"To work as an ornithologist."},{"w":"ossify","tr":"kemikleşmek / katılaşmak / değişmez olmak","te":"Verb","tt":"Fiil","de":"To become hard like bone; or to become unable to change","dt":"Kemik gibi sertleşmek; veya değişemez hale gelmek","e1":"Ossified attitudes.","e1t":"Kemikleşmiş (değişmez) tutumlar.","e2":"The cartilage ossifies over time.","e2t":"Kıkırdak zamanla kemikleşir."},{"w":"ostensible","tr":"görünürdeki / sözde","te":"Adjective","tt":"Sıfat","de":"Apparent or stated, but perhaps not true","dt":"Görünürde olan veya belirtilen ama belki de gerçek olmayan","e1":"The ostensible reason for his absence.","e1t":"Devamsızlığının görünürdeki (sözde) nedeni.","e2":"Their ostensible goal.","e2t":"Sözde amaçları."},{"w":"oust","tr":"kovmak / yerinden etmek / görevden uzaklaştırmak","te":"Verb","tt":"Fiil","de":"To force someone to leave a position of power","dt":"Birini güçlü bir konumdan ayrılmaya zorlamak","e1":"The president was ousted in a coup.","e1t":"Başkan bir darbeyle devrildi (kovuldu).","e2":"To oust a rival.","e2t":"Bir rakibi saf dışı bırakmak."},{"w":"outlay","tr":"harcama / masraf / maliyet","te":"Noun","tt":"İsim","de":"An amount of money spent on something new","dt":"Yeni bir şeye harcanan para miktarı","e1":"A large initial outlay.","e1t":"Büyük bir başlangıç masrafı (yatırımı).","e2":"To reduce the annual outlay.","e2t":"Yıllık harcamayı azaltmak."},{"w":"outmoded","tr":"eski moda / devri geçmiş / demode","te":"Adjective","tt":"Sıfat","de":"No longer useful or modern","dt":"Artık faydalı veya modern olmayan","e1":"Outmoded ideas.","e1t":"Devri geçmiş fikirler.","e2":"Outmoded equipment.","e2t":"Eski moda (kullanışsız) ekipman."},{"w":"outstrip","tr":"geride bırakmak / geçmek / üstün gelmek","te":"Verb","tt":"Fiil","de":"To become larger, more important, or more successful than something else","dt":"Başka bir şeyden daha büyük, önemli veya başarılı hale gelmek","e1":"Demand for the product is outstripping supply.","e1t":"Ürüne olan talep arzı geride bırakıyor.","e2":"He outstripped all the other runners.","e2t":"Diğer tüm koşucuları geride bıraktı."},{"w":"outwit","tr":"zekasıyla yenmek / atlatmak / kurnazlıkla alt etmek","te":"Verb","tt":"Fiil","de":"To get an advantage over someone by being cleverer","dt":"Daha zeki davranarak birine karşı avantaj elde etmek","e1":"The fox managed to outwit the hunters.","e1t":"Tilki avcıları atlatmayı (zekasıyla yenmeyi) başardı.","e2":"To outwit an opponent.","e2t":"Bir rakibi kurnazlıkla alt etmek."},{"w":"overbearing","tr":"baskıcı / otoriter / baskın / kibirli","te":"Adjective","tt":"Sıfat","de":"Trying to control other people in an unpleasant way","dt":"Diğer insanları nahoş bir şekilde kontrol etmeye çalışan","e1":"An overbearing mother.","e1t":"Baskıcı bir anne.","e2":"He has an overbearing personality.","e2t":"Tahakküm edici (baskıcı) bir kişiliği var."},{"w":"overblown","tr":"abartılı / şişirilmiş / geçmiş (çiçek vb.)","te":"Adjective","tt":"Sıfat","de":"Made to seem more important than it really is","dt":"Gerçekte olduğundan daha önemliymiş gibi gösterilen","e1":"An overblown reputation.","e1t":"Şişirilmiş (abartılı) bir itibar.","e2":"The whole story was overblown by the press.","e2t":"Tüm hikaye basın tarafından abartıldı."},{"w":"overdose","tr":"aşırı doz / doz aşımı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Too much of a drug taken at one time","dt":"Bir seferde alınan çok fazla ilaç/uyuşturucu","e1":"He died of a drug overdose.","e1t":"Aşırı doz uyuşturucudan öldü.","e2":"To overdose on sleeping pills.","e2t":"Uyku hapından aşırı doz almak."},{"w":"overestimate","tr":"abartmak / gözünde büyütmek / yüksek tahmin etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To guess an amount or value that is too high","dt":"Bir miktar veya değeri olduğundan yüksek tahmin etmek","e1":"Never overestimate your opponent.","e1t":"Rakibini asla gözünde büyütme.","e2":"To overestimate the cost.","e2t":"Maliyeti yüksek tahmin etmek."},{"w":"override","tr":"geçersiz kılmak / reddetmek / çiğnemek / manuel kontrol","te":"Verb/Noun","tt":"Fiil/İsim","de":"To use authority to change a decision; or to be more important","dt":"Bir kararı değiştirmek için yetki kullanmak; veya daha önemli olmak","e1":"The central government can override local decisions.","e1t":"Merkezi hükümet yerel kararları geçersiz kılabilir.","e2":"Considerations of safety override everything else.","e2t":"Güvenlik mülahazaları diğer her şeyden daha önemlidir (üstündür)."},{"w":"overshadow","tr":"gölgede bırakmak / gölgelemek / üzmek","te":"Verb","tt":"Fiil","de":"To cause someone to seem less important; or to make a place sad","dt":"Birinin daha az önemli görünmesine neden olmak; veya bir yeri hüzünlendirmek","e1":"Her success was overshadowed by her health problems.","e1t":"Başarısı sağlık sorunları nedeniyle gölgelendi.","e2":"He was always overshadowed by his famous brother.","e2t":"Her zaman ünlü kardeşinin gölgesinde kaldı."},{"w":"overt","tr":"açık / gizli olmayan / meydanda","te":"Adjective","tt":"Sıfat","de":"Done or shown publicly and not hidden","dt":"Gizlenmeden, herkesin önünde yapılan veya gösterilen","e1":"Overt hostility.","e1t":"Açık düşmanlık.","e2":"There is no overt signs of improvement.","e2t":"Belirgin (açık) bir düzelme belirtisi yok. (Not: 'Covert' kelimesinin zıttıdır)."},{"w":"overture","tr":"giriş / teklif / uvertür (müzik)","te":"Noun","tt":"İsim","de":"A piece of music at the beginning; or an attempt to start a relationship","dt":"Başlangıçtaki müzik parçası; veya bir ilişkiyi başlatma girişimi","e1":"The opera began with a short overture.","e1t":"Opera kısa bir uvertürle başladı.","e2":"To make peace overtures.","e2t":"Barış tekliflerinde (girişimlerinde) bulunmak."},{"w":"overweening","tr":"kibirli / aşırı / kendini beğenmiş","te":"Adjective","tt":"Sıfat","de":"Being too proud or confident","dt":"Aşırı gururlu veya kendine güvenen","e1":"Overweening ambition.","e1t":"Gözü dönmüş (aşırı) hırs.","e2":"Overweening pride.","e2t":"Kibirli gurur."},{"w":"overwrought","tr":"aşırı heyecanlı / bitkin / fazla süslü","te":"Adjective","tt":"Sıfat","de":"In a state of being upset, nervous, or worried","dt":"Çok üzgün, gergin veya endişeli bir durumda","e1":"She was tired and overwrought.","e1t":"Yorgun ve sinirleri bozulmuş (bitkin) haldeydi.","e2":"An overwrought writing style.","e2t":"Gereğinden fazla süslü yazı tarzı."},{"w":"ovoid","tr":"yumurta şeklinde / oval","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Shaped like an egg","dt":"Yumurta biçiminde","e1":"An ovoid fruit.","e1t":"Yumurta şeklinde bir meyve.","e2":"Ovoid structures in biology.","e2t":"Biyolojideki oval yapılar."},{"w":"pacifist","tr":"barışsever / savaş karşıtı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who believes that war and violence are always wrong","dt":"Savaş ve şiddetin her zaman yanlış olduğuna inanan kişi","e1":"He was a lifelong pacifist.","e1t":"Ömrü boyunca savaş karşıtıydı.","e2":"Pacifist beliefs.","e2t":"Barışçıl inançlar."},{"w":"paean","tr":"övgü şarkısı / methiye / zafer şarkısı","te":"Noun","tt":"İsim","de":"A song, film, or piece of writing that praises someone (formal)","dt":"Birini öven şarkı, film veya yazı (resmi)","e1":"A paean to the joys of childhood.","e1t":"Çocukluk neşesine bir methiye.","e2":"To sing a paean of praise.","e2t":"Övgü şarkıları söylemek."},{"w":"palatial","tr":"saray gibi / görkemli / muhteşem","te":"Adjective","tt":"Sıfat","de":"Large and highly decorated like a palace","dt":"Saray gibi büyük ve görkemli","e1":"A palatial hotel.","e1t":"Saray gibi (muhteşem) bir otel.","e2":"Palatial living quarters.","e2t":"Görkemli yaşam alanları."},{"w":"paleontology / palaeontology","tr":"fosil bilimi / paleontoloji","te":"Noun","tt":"İsim","de":"The scientific study of fossils","dt":"Fosillerin bilimsel olarak incelenmesi","e1":"A professor of paleontology.","e1t":"Fosil bilimi profesörü.","e2":"Advances in paleontology.","e2t":"Paleontolojideki gelişmeler."},{"w":"palette","tr":"palet / renk yelpazesi","te":"Noun","tt":"İsim","de":"A board on which a painter mixes colors; or the range of colors used","dt":"Ressamın renkleri karıştırdığı levha; veya kullanılan renklerin bütünü","e1":"The artist's palette.","e1t":"Ressamın paleti.","e2":"A soft palette of blues and greens.","e2t":"Mavi ve yeşillerden oluşan yumuşak bir renk yelpazesi."},{"w":"pall","tr":"örtü / sıkıcı olmak / tadı kaçmak / tabut örtüsü","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thick cloud of smoke or dust; or to become boring","dt":"Yoğun duman veya toz bulutu; veya sıkıcı hale gelmek","e1":"A pall of smoke hung over the city.","e1t":"Şehrin üzerinde bir duman bulutu asılı kaldı.","e2":"The fun began to pall after a few hours.","e2t":"Birkaç saat sonra eğlencenin tadı kaçmaya (sıkıcı gelmeye) başladı."},{"w":"palliate","tr":"hafifletmek / geçici çare bulmak / yatıştırmak","te":"Verb","tt":"Fiil","de":"To make a bad situation or symptom seem less severe","dt":"Kötü bir durumu veya semptomu daha az şiddetli kılmak","e1":"To palliate the symptoms of a disease.","e1t":"Bir hastalığın semptomlarını hafifletmek.","e2":"Palliative care (hospice).","e2t":"Destekleyici (hafifletici) bakım."},{"w":"pallid","tr":"solgun / cansız / sönük","te":"Adjective","tt":"Sıfat","de":"Very pale, especially in a way that looks unhealthy; or boring","dt":"Özellikle sağlıksız görünecek kadar solgun; veya sıkıcı","e1":"A pallid complexion.","e1t":"Solgun bir beniz.","e2":"A pallid performance.","e2t":"Cansız (sönük) bir performans."},{"w":"palpable","tr":"hissedilebilir / belirgin / elle tutulur","te":"Adjective","tt":"Sıfat","de":"So obvious that it can easily be seen or known","dt":"Kolayca görülebilen veya bilinebilen kadar bariz","e1":"A palpable sense of relief.","e1t":"Elle tutulur (belirgin) bir rahatlama hissi.","e2":"The tension in the room was palpable.","e2t":"Odadaki gerginlik hissediliyordu."},{"w":"palpitate","tr":"çarpmak (kalp) / titremek / küt küt atmak","te":"Verb","tt":"Fiil","de":"(Of the heart) to beat very fast and irregularly","dt":"(Kalp için) çok hızlı ve düzensiz atmak","e1":"My heart began to palpitate with fear.","e1t":"Kalbim korkudan küt küt atmaya başladı.","e2":"Palpitations (noun).","e2t":"Kalp çarpıntısı."},{"w":"paltry","tr":"değersiz / miktar olarak çok az / ehemmiyetsiz","te":"Adjective","tt":"Sıfat","de":"(Of an amount) very small and of little value","dt":"(Miktar için) çok az ve değersiz","e1":"A paltry sum of money.","e1t":"Önemsiz (küçük) bir miktar para.","e2":"A paltry excuse.","e2t":"Değersiz (zayıf) bir bahane."},{"w":"panacea","tr":"her derde deva / evrensel çare","te":"Noun","tt":"İsim","de":"Something that will solve all problems","dt":"Tüm sorunları çözecek olan şey","e1":"Technology is not a panacea for all our problems.","e1t":"Teknoloji tüm sorunlarımız için her derde deva bir ilaç değildir.","e2":"A panacea for the economy.","e2t":"Ekonomi için sihirli değnek (çare)."},{"w":"panache","tr":"gösteriş / fiyaka / şatafat","te":"Noun","tt":"İsim","de":"A stylish and confident way of doing things","dt":"Bir şeyi yaparken sergilenen şık ve kendinden emin tavır","e1":"He performed the task with great panache.","e1t":"İşi büyük bir fiyakayla (ustalıkla) yaptı.","e2":"To have panache.","e2t":"Gösterişli/tarz sahibi olmak."},{"w":"pandemic","tr":"salgın / pandemik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a disease) existing in a whole country or the world","dt":"(Hastalık için) tüm ülkede veya dünyada var olan","e1":"A global pandemic.","e1t":"Küresel salgın.","e2":"Pandemic flu.","e2t":"Pandemik grip."},{"w":"pandemonium","tr":"kargaşa / curcuna / tam bir kaos","te":"Noun","tt":"İsim","de":"A situation in which there is a lot of noise and confusion","dt":"Çok fazla gürültü ve karışıklığın olduğu durum","e1":"Pandemonium broke out when the goal was scored.","e1t":"Gol atıldığında tam bir curcuna (kargaşa) koptu.","e2":"It was absolute pandemonium.","e2t":"Tam bir kaostu."},{"w":"pander","tr":"kötü arzulara hizmet etmek / yaranmak / taviz vermek","te":"Verb","tt":"Fiil","de":"To give someone what they want, especially if it is not right","dt":"Özellikle doğru olmasa bile birinin (kötü) isteklerine hizmet etmek","e1":"The film panders to the audience's worst instincts.","e1t":"Film, seyircinin en kötü içgüdülerine hitap ediyor (hizmet ediyor).","e2":"To pander to the masses.","e2t":"Kitlelere yaranmaya çalışmak."},{"w":"panegyric","tr":"övgü / methiye / sitayiş","te":"Noun","tt":"İsim","de":"A speech or piece of writing that praises someone highly","dt":"Birini yüksek derecede öven konuşma veya yazı","e1":"A panegyric on the late president.","e1t":"Merhum başkan üzerine bir methiye.","e2":"To deliver a panegyric.","e2t":"Övgü dolu bir söylev vermek."},{"w":"pantomime","tr":"pandomim / sözsüz oyun / saçmalık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A type of play using only gestures; or a ridiculous situation","dt":"Sadece jestlerin kullanıldığı oyun türü; veya gülünç durum","e1":"To perform in pantomime.","e1t":"Pandomim yapmak.","e2":"The trial was a complete pantomime.","e2t":"Duruşma tam bir saçmalıktı (tiyatroydu)."},{"w":"papyrus","tr":"papirüs","te":"Noun","tt":"İsim","de":"A paper","dt":"like material used in ancient Egypt; or the plant","e1":"Antik Mısır'da kullanılan kağıt benzeri malzeme; veya bitkisi","e1t":"Ancient papyrus scrolls.","e2":"Antik papirüs tomarları.","e2t":"To write on papyrus."},{"w":"parable","tr":"kıssadan hisse / mesel / temsil","te":"Noun","tt":"İsim","de":"A short simple story that teaches a moral or religious lesson","dt":"Ahlaki veya dini ders veren kısa ve basit hikaye","e1":"The parable of the Prodigal Son.","e1t":"Kayıp Oğul meseli.","e2":"To tell a parable.","e2t":"Bir kıssa anlatmak."},{"w":"paragon","tr":"mükemmellik örneği / kusursuz tip / ideal","te":"Noun","tt":"İsim","de":"A person or thing that is perfect or has a lot of a good quality","dt":"Mükemmel olan veya iyi bir niteliğe fazlasıyla sahip olan kişi/şey","e1":"A paragon of virtue.","e1t":"Erdem timsali (kusursuz örnek).","e2":"He is not exactly a paragon of efficiency.","e2t":"Tam olarak bir verimlilik abidesi sayılmaz."},{"w":"parallelism","tr":"paralellik / benzerlik","te":"Noun","tt":"İsim","de":"The state of being parallel or having similar features","dt":"Paralel olma veya benzer özelliklere sahip olma durumu","e1":"The parallelism between the two historical events.","e1t":"İki tarihi olay arasındaki paralellik.","e2":"Grammatical parallelism.","e2t":"Dilbilgisel paralellik (yapı benzerliği)."},{"w":"paraphernalia","tr":"ıvır zıvır / teçhizat / pırtı","te":"Noun","tt":"İsim","de":"A large number of objects used for a particular activity","dt":"Belirli bir faaliyet için kullanılan çok sayıda nesne","e1":"Photography paraphernalia.","e1t":"Fotoğrafçılık ekipmanları (ıvır zıvırı).","e2":"Drug paraphernalia.","e2t":"Uyuşturucu düzeneği/malzemeleri."},{"w":"paraphrase","tr":"başka sözcüklerle anlatmak / açımlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To repeat something using different words to make it clearer","dt":"Daha net kılmak için bir şeyi farklı kelimelerle tekrar etmek","e1":"Can you paraphrase the main argument?","e1t":"Ana iddiayı başka sözcüklerle anlatabilir misin?","e2":"A paraphrase of the text.","e2t":"Metnin açımlaması."},{"w":"parched","tr":"kurumuş / kavrulmuş / çok susamış","te":"Adjective","tt":"Sıfat","de":"Very dry, especially because of hot weather; or very thirsty","dt":"Özellikle sıcak hava nedeniyle kurumuş; veya çok susamış","e1":"Parched earth.","e1t":"Çatlamış (kurumuş) toprak.","e2":"I'm absolutely parched!","e2t":"Susuzluktan dilim damağım kurudu!"},{"w":"pariah","tr":"dışlanmış / parya / toplum dışı kişi","te":"Noun","tt":"İsim","de":"A person who is not accepted by a social group","dt":"Sosyal bir grup tarafından kabul edilmeyen (dışlanan) kişi","e1":"He became a social pariah after the scandal.","e1t":"Skandaldan sonra toplumdan dışlanmış (parya) biri haline geldi.","e2":"A pariah state.","e2t":"Uluslararası toplumdan dışlanmış devlet."},{"w":"parlance","tr":"konuşma tarzı / terminoloji / tabir","te":"Noun","tt":"Isim","de":"A particular way of speaking used by a group","dt":"Bir grup tarafından kullanılan özel konuşma tarzı","e1":"In common parlance.","e1t":"Halk arasındaki tabiriyle (konuşma dilinde).","e2":"Legal parlance.","e2t":"Hukuk terminolojisi."},{"w":"parley","tr":"görüşme / müzakere / pazarlık","te":"Noun/Verb","tt":"İsim/Fiil","de":"A discussion between enemies to find a solution","dt":"Düşmanlar arasında bir çözüm bulmak için yapılan görüşme","e1":"To hold a parley.","e1t":"Bir görüşme (müzakere) yapmak.","e2":"To parley with the enemy.","e2t":"Düşmanla görüşmek."},{"w":"parochial","tr":"dar görüşlü / dar kapsamlı / kilise bölgesine ait","te":"Adjective","tt":"Sıfat","de":"Showing interest only in a narrow local area; narrow","dt":"minded","e1":"Sadece dar bir yerel alanla ilgilenen; dar görüşlü","e1t":"A parochial outlook on life.","e2":"Hayata dar bir pencereden (dar görüşlü) bakış.","e2t":"Parochial schools."},{"w":"paroxysm","tr":"nöbet / kriz / ani patlama","te":"Noun","tt":"İsim","de":"A sudden strong feeling or physical movement that cannot be controlled","dt":"Kontrol edilemeyen ani ve güçlü duygu veya fiziksel hareket","e1":"A paroxysm of coughing.","e1t":"Öksürük nöbeti.","e2":"A paroxysm of rage.","e2t":"Öfke patlaması (krizi)."},{"w":"parry","tr":"savuşturmak / geçiştirmek / defetmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To defend yourself by pushing a weapon aside; or to avoid a question","dt":"Bir silahı yana iterek kendini savunmak; veya bir soruyu geçiştirmek","e1":"He parried the blow with his sword.","e1t":"Darbeyi kılıcıyla savuşturdu.","e2":"She parried the reporter's questions.","e2t":"Muhabirin sorularını geçiştirdi."},{"w":"parsimony","tr":"cimrilik / aşırı tutumluluk","te":"Noun","tt":"İsim","de":"Extreme unwillingness to spend money (formal)","dt":"Para harcamaya karşı aşırı isteksizlik (resmi)","e1":"He was known for his parsimony.","e1t":"Cimriliğiyle bilinirdi.","e2":"Parsimonious (adjective).","e2t":"Pinti."},{"w":"partiality","tr":"adam kayırma / taraflılık / düşkünlük","te":"Noun","tt":"İsim","de":"Unfair support for one person or group; or a liking for something","dt":"Bir kişi veya gruba haksız destek; veya bir şeye duyulan düşkünlük","e1":"The judge was accused of partiality.","e1t":"Hakim taraflılıkla (adam kayırmakla) suçlandı.","e2":"A partiality for spicy food.","e2t":"Baharatlı yemeklere olan düşkünlük."},{"w":"partition","tr":"bölme / paravan / bölümlere ayırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A structure that divides a room; or the division of a country","dt":"Bir odayı bölen yapı; veya bir ülkenin bölünmesi","e1":"A glass partition.","e1t":"Cam bölme.","e2":"The partition of India in 1947.","e2t":"Hindistan'ın 1947'deki bölünmesi."},{"w":"passé","tr":"modası geçmiş / devri geçmiş / demode","te":"Adjective","tt":"Sıfat","de":"No longer fashionable or useful","dt":"Artık moda veya kullanışlı olmayan","e1":"His ideas are a bit passé now.","e1t":"Fikirlerinin modası artık biraz geçti.","e2":"Passé styles.","e2t":"Demode tarzlar."},{"w":"pastiche","tr":"taklit eser / kolaj / karma eser","te":"Noun/Verb","tt":"İsim/Fiil","de":"A piece of art or music that intentionally copies the style of another","dt":"Başka bir sanat/müzik tarzını kasten taklit eden eser","e1":"The movie is a pastiche of 1950s thrillers.","e1t":"Film, 1950'lerin gerilim filmlerinin bir taklididir (kolajıdır).","e2":"Architectural pastiche.","e2t":"Mimari taklit eser."},{"w":"pastoral","tr":"kırsal / çobanıl / dini rehberlik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the countryside or shepherds; or giving spiritual advice","dt":"Kırsal yaşam veya çobanlarla ilgili; veya manevi rehberlik veren","e1":"A pastoral landscape.","e1t":"Kırsal manzara.","e2":"Pastoral poetry.","e2t":"Çobanıl (pastoral) şiir."},{"w":"pathogenic","tr":"hastalık yapıcı / patojenik","te":"Adjective","tt":"Sıfat","de":"Able to cause disease","dt":"Hastalık oluşturma yeteneği olan","e1":"Pathogenic bacteria.","e1t":"Hastalık yapıcı bakteriler.","e2":"The study of pathogenic organisms.","e2t":"Patojenik organizmaların incelenmesi."},{"w":"pathological","tr":"hastalıklı / patolojik / kontrol edilemez","te":"Adjective","tt":"Sıfat","de":"Relating to a disease; or (of behavior) not normal or controlled","dt":"Bir hastalıkla ilgili; veya (davranış için) normal olmayan/kontrol edilemeyen","e1":"A pathological liar.","e1t":"Patolojik (istikrarlı ve kontrolsüz) yalancı.","e2":"Pathological changes in the brain.","e2t":"Beyindeki patolojik değişimler."},{"w":"pathos","tr":"acıma duygusu / dokunaklılık","te":"Noun","tt":"İsim","de":"A quality in a situation that makes you feel sadness or pity","dt":"Bir durumdaki üzüntü veya acıma uyandıran nitelik","e1":"The film is full of pathos.","e1t":"Film dokunaklılık (acıma duygusu) dolu.","e2":"To speak with great pathos.","e2t":"Büyük bir dokunaklılıkla konuşmak."},{"w":"patina","tr":"yüzey tabakası / pas / olgunluk belirtisi","te":"Noun","tt":"İsim","de":"A green layer that forms on copper; or a surface appearance of age","dt":"Bakır üzerindeki yeşil tabaka; veya bir yüzeydeki yaşanmışlık belirtisi","e1":"A fine patina of age on the furniture.","e1t":"Mobilya üzerindeki güzel bir yaşanmışlık (olgunluk) tabakası.","e2":"The bronze had a natural green patina.","e2t":"Bronzun doğal bir yeşil pası (tabakası) vardı."},{"w":"patois","tr":"lehçe / yerel ağız / jargo","te":"Noun","tt":"İsim","de":"A form of a language that is different from the standard form","dt":"Standart formdan farklı olan yerel dil biçimi","e1":"He spoke in the local patois.","e1t":"Yerel ağızla (lehçeyle) konuştu.","e2":"Prison patois.","e2t":"Hapishane jargonu."},{"w":"patrician","tr":"soylu / asilzade / aristokrat","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person of high social class; or having a high social class appearance","dt":"Yüksek sosyal sınıftan olan kişi; veya soylu görünüşlü","e1":"A patrician family.","e1t":"Soylu bir aile.","e2":"His patrician features.","e2t":"Onun aristokratik çehresi."},{"w":"patronize / patronise","tr":"himaye etmek / küçümsemek / müşterisi olmak","te":"Verb","tt":"Fiil","de":"To treat someone as if they are less intelligent; or to be a regular customer","dt":"Birine tepeden bakmak (küçümsemek); veya bir yerin sürekli müşterisi olmak","e1":"Don't patronize me!","e1t":"Benimle çocukmuşum gibi (küçümseyerek) konuşma!","e2":"To patronize a local restaurant.","e2t":"Yerel bir restoranın müdavimi olmak."},{"w":"paucity","tr":"kıtlık / azlık / yetersizlik","te":"Noun","tt":"İsim","de":"The fact that there is too little of something (formal)","dt":"Bir şeyin çok az olması durumu (resmi)","e1":"A paucity of information.","e1t":"Bilgi kıtlığı.","e2":"There is a paucity of evidence.","e2t":"Kanıt yetersizliği (azlığı) var."},{"w":"pauper","tr":"yoksul / fakir / muhtaç kişi","te":"Noun","tt":"İsim","de":"A very poor person","dt":"Çok fakir kişi","e1":"He died a pauper.","e1t":"Bir yoksul olarak (beş parasız) öldü.","e2":"Pauper's grave.","e2t":"Kimsesizler (yoksullar) mezarı."},{"w":"peccadillo","tr":"küçük hata / kabahat / ufak kusur","te":"Noun","tt":"İsim","de":"A small fault or mistake, especially a social one","dt":"Özellikle sosyal alanda yapılan küçük hata veya kusur","e1":"We all have our little peccadilloes.","e1t":"Hepimizin küçük kusurları (günahları) vardır.","e2":"A minor sexual peccadillo.","e2t":"Küçük bir cinsel kaçamak (kabahat)."},{"w":"pecuniary","tr":"parasal / mali","te":"Adjective","tt":"Sıfat","de":"Relating to money (formal)","dt":"Para ile ilgili (resmi)","e1":"Pecuniary interest.","e1t":"Maddi (parasal) çıkar.","e2":"To suffer a pecuniary loss.","e2t":"Maddi zarara uğramak."},{"w":"pedagogue / pedagog","tr":"öğretmen / eğitimci / bilgiçlik taslayan öğretmen","te":"Noun","tt":"İsim","de":"A teacher, especially one who is strict or formal","dt":"Özellikle sert veya kuralcı olan öğretmen","e1":"A great pedagogue.","e1t":"Büyük bir eğitimci.","e2":"He is more of a pedagogue than a scholar.","e2t":"Bir bilginden ziyade bir eğitimcidir."},{"w":"pedant","tr":"bilgiçlik taslayan / kuralcı / ayrıntıcı","te":"Noun","tt":"İsim","de":"A person who cares too much about small details or rules","dt":"Küçük detaylara veya kurallara aşırı önem veren kişi","e1":"Don't be such a pedant!","e1t":"Bu kadar ayrıntıcı (bilgiç) olma!","e2":"Intellectual pedant.","e2t":"Entelektüel bilgiç."},{"w":"pediatrician / paediatrician","tr":"çocuk doktoru","te":"Noun","tt":"İsim","de":"A doctor who studies and treats the diseases of children","dt":"Çocuk hastalıkları uzmanı","e1":"Our pediatrician is very kind.","e1t":"Çocuk doktorumuz çok nazik.","e2":"To specialize as a pediatrician.","e2t":"Çocuk doktoru olarak uzmanlaşmak."},{"w":"peerless","tr":"eşsiz / benzersiz / rakipsiz","te":"Adjective","tt":"Sıfat","de":"Better than all others","dt":"Diğer her şeyden daha iyi olan","e1":"A peerless performance.","e1t":"Eşsiz bir performans.","e2":"He is a peerless athlete.","e2t":"O rakipsiz bir sporcudur."},{"w":"pejorative","tr":"aşağılayıcı / küçümseyici / yerici","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a word) expressing disapproval or lack of respect","dt":"(Kelime için) onaylamama veya saygısızlık ifade eden","e1":"\"Spinster\" is a pejorative term.","e1t":"\"Evde kalmış kız\" aşağılayıcı bir terimdir.","e2":"To use a word in a pejorative sense.","e2t":"Bir kelimeyi küçümseyici anlamda kullanmak."},{"w":"pellucid","tr":"şeffaf / berrak / çok net","te":"Adjective","tt":"Sıfat","de":"Very clear and transparent; or very easy to understand","dt":"Çok berrak ve şeffaf; veya anlaşılması çok kolay","e1":"Pellucid water.","e1t":"Berrak su.","e2":"A pellucid writing style.","e2t":"Çok net (anlaşılır) bir yazı tarzı."},{"w":"penance","tr":"kefaret / pişmanlık göstergesi","te":"Noun","tt":"İsim","de":"An act that shows you are sorry for a sin","dt":"Bir günah için üzgün olunduğunu gösteren eylem","e1":"To do penance for one's sins.","e1t":"Günahları için kefaret ödemek.","e2":"As a formal penance.","e2t":"Resmi bir pişmanlık göstergesi olarak."},{"w":"penchant","tr":"eğilim / düşkünlük / merak","te":"Noun","tt":"İsim","de":"A strong liking for something","dt":"Bir şeye duyulan güçlü ilgi/düşkünlük","e1":"He has a penchant for fast cars.","e1t":"Hızlı arabalara karşı bir düşkünlüğü var.","e2":"A penchant for drama.","e2t":"Dramaya (abartıya) eğilim."},{"w":"pendent / pendant","tr":"asılı / sarkan / kolye ucu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Hanging down; or a piece of jewelry worn on a chain","dt":"Aşağı sarkan; veya zincire takılan mücevher","e1":"Pendent branches.","e1t":"Sarkan dallar.","e2":"A diamond pendant.","e2t":"Elmas kolye ucu."},{"w":"pendulous","tr":"sarkan / sallanan","te":"Adjective","tt":"Sıfat","de":"Hanging down heavily","dt":"Ağır bir şekilde aşağı sarkan","e1":"Pendulous breasts.","e1t":"Sarkan göğüsler.","e2":"The pendulous nest of the weaver bird.","e2t":"Dokumacı kuşunun sarkan yuvası."},{"w":"penitent","tr":"pişman / tövbe eden","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Showing that you are sorry for something wrong you have done","dt":"Yapılan bir yanlıştan dolayı üzgün olduğunu gösteren","e1":"A penitent expression.","e1t":"Pişman bir ifade.","e2":"To be truly penitent.","e2t":"Gerçekten pişman olmak."},{"w":"penury","tr":"yoksulluk / sefalet / darlık","te":"Noun","tt":"İsim","de":"The state of being extremely poor (formal)","dt":"Aşırı fakir olma durumu (resmi)","e1":"To live in penury.","e1t":"Sefalet içinde yaşamak.","e2":"He was reduced to penury.","e2t":"Yoksulluğa mahkum oldu."},{"w":"perceptive","tr":"sezgili / anlayışlı / keskin gözlemli","te":"Adjective","tt":"Sıfat","de":"Very good at noticing and understanding things","dt":"Şeyleri fark etme ve anlamada çok iyi olan","e1":"A very perceptive remark.","e1t":"Çok sezgili (yerinde) bir yorum.","e2":"Perceptive observers of human nature.","e2t":"İnsan doğasının keskin gözlemcileri."},{"w":"percussion","tr":"vuruş / vurmalı çalgılar","te":"Noun","tt":"İsim","de":"Musical instruments that you play by hitting them","dt":"Vurularak çalınan müzik aletleri","e1":"The percussion section of the orchestra.","e1t":"Orkestranın vurmalı çalgılar bölümü.","e2":"Percussion caps (explosives).","e2t":"Patlar başlıklar."},{"w":"perdition","tr":"cehennemlik olma / ebedi azap / mahvoluş","te":"Noun","tt":"Isim","de":"(In some religions) the state of being punished for ever after death","dt":"Ölümden sonra sonsuza dek cezalandırılma durumu","e1":"To save one's soul from perdition.","e1t":"Ruhunu ebedi azaptan kurtarmak.","e2":"Road to perdition.","e2t":"Mahvoluşa giden yol."},{"w":"peregrination","tr":"seyahat / yolculuk / gezinti","te":"Noun","tt":"Isim","de":"A long journey, especially on foot (formal)","dt":"Özellikle yaya yapılan uzun yolculuk (resmi)","e1":"His peregrinations through Europe.","e1t":"Onun Avrupa seyahatleri.","e2":"To continue one's peregrinations.","e2t":"Yolculuğuna devam etmek."},{"w":"peremptory","tr":"kesin / emir kipiyle / diktatörce","te":"Adjective","tt":"Sıfat","de":"Expecting to be obeyed immediately and without question","dt":"Sorgulanmadan derhal itaat edilmesini bekleyen","e1":"A peremptory command.","e1t":"Kesin (tartışılmaz) bir emir.","e2":"He spoke in a peremptory tone.","e2t":"Emir verircesine (sert) bir tonla konuştu."},{"w":"perfidious","tr":"hain / sadakatsiz / sinsi","te":"Adjective","tt":"Sıfat","de":"Unable to be trusted; disloyal (formal)","dt":"Güvenilemez; sadakatsiz (resmi)","e1":"A perfidious ally.","e1t":"Hain bir müttefik.","e2":"Perfidious behavior.","e2t":"Sadakatsiz davranış."},{"w":"perforate","tr":"delmek / delik deşik etmek","te":"Verb","tt":"Fiil","de":"To make a hole or holes in something","dt":"Bir şeyde delik veya delikler açmak","e1":"The bullet perforated his lung.","e1t":"Kurşun akciğerini delip geçti.","e2":"Perforated paper.","e2t":"Delikli (tırtıklı) kağıt."},{"w":"perfunctory","tr":"baştan savma / üstünkörü / adet yerini bulsun diye","te":"Adjective","tt":"Sıfat","de":"Done quickly and without interest or care","dt":"İlgi veya özen göstermeden, hızlıca yapılan","e1":"A perfunctory smile.","e1t":"Baştan savma (zoraki) bir gülümseme.","e2":"He gave the report a perfunctory glance.","e2t":"Rapora üstünkörü bir göz attı."},{"w":"peripheral","tr":"çevresel / ikincil / yan / çevre birimi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not as important as the main part; or relating to the edge","dt":"Ana parçadan daha az önemli; veya kenarla ilgili","e1":"Peripheral vision.","e1t":"Çevresel görüş (göz ucuyla görme).","e2":"A peripheral issue.","e2t":"İkincil (yan) bir mesele."},{"w":"periphery","tr":"kenar / dış yüzey / çevre","te":"Noun","tt":"İsim","de":"The outer edge of an area","dt":"Bir alanın dış kenarı","e1":"On the periphery of the city.","e1t":"Şehrin kenarında (banliyösünde).","e2":"To stay on the periphery of the crowd.","e2t":"Kalabalığın kenarında durmak."},{"w":"permeable","tr":"geçirgen / sızdırabilir","te":"Adjective","tt":"Sıfat","de":"Allowing liquid or gas to pass through it","dt":"Sıvı veya gazın içinden geçmesine izin veren","e1":"Permeable membrane.","e1t":"Geçirgen zar.","e2":"Certain rocks are permeable to water.","e2t":"Bazı kayalar suyu geçirir."},{"w":"pernicious","tr":"zararlı / sinsi / kötücül","te":"Adjective","tt":"Sıfat","de":"Having a very harmful effect or influence","dt":"Çok zararlı bir etkisi veya nüfuzu olan","e1":"The pernicious effects of poverty.","e1t":"Yoksulluğun sinsi (zararlı) etkileri.","e2":"A pernicious habit.","e2t":"Kötücül bir alışkanlık."},{"w":"perpetuate","tr":"sürdürmek / devam ettirmek / ölümsüzleştirmek","te":"Verb","tt":"Fiil","de":"To cause something to continue for a long time","dt":"Bir şeyin uzun süre devam etmesini sağlamak","e1":"To perpetuate a myth.","e1t":"Bir efsaneyi sürdürmek.","e2":"The movie perpetuates stereotypes.","e2t":"Film, kalıplaşmış yargıları devam ettiriyor."},{"w":"perquisite / perk","tr":"yan hak / ikramiye / imtiyaz","te":"Noun","tt":"İsim","de":"An advantage or extra thing you get because of your job","dt":"İşten dolayı elde edilen avantaj veya ekstra şey","e1":"A company car is a perquisite of the job.","e1t":"Şirket arabası işin bir yan hakkıdır.","e2":"The perquisites of power.","e2t":"Gücün getirdiği imtiyazlar."},{"w":"personable","tr":"hoş / cana yakın / yakışıklı","te":"güzel","tt":"Adjective","de":"Sıfat","dt":"Having a pleasant appearance and character","e1":"Hoş bir görünüşü ve karakteri olan","e1t":"A very personable young man.","e2":"Çok cana yakın (hoş) bir genç adam.","e2t":"She is intelligent and personable."},{"w":"perspicacious","tr":"anlayışlı / ferasetli / keskin zekalı","te":"Adjective","tt":"Sıfat","de":"Quick to judge and understand situations correctly","dt":"Durumları doğru anlama ve yargılamada hızlı olan","e1":"A perspicacious observer.","e1t":"Ferasetli (keskin) bir gözlemci.","e2":"Perspicacious judgment.","e2t":"Keskin bir yargı."},{"w":"picayune","tr":"önemsiz / değersiz / küçük miktar","te":"Adjective","tt":"Sıfat","de":"Having little value or importance (informal)","dt":"Değeri veya önemi az olan","e1":"A picayune amount of money.","e1t":"Ehemmiyetsiz miktarda para.","e2":"Don't worry about such picayune details.","e2t":"Öyle önemsiz detaylar için endişelenme."},{"w":"piecemeal","tr":"parça parça / azar azar / bölük pörçük","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Done or happening gradually and not as a complete whole","dt":"Tam bir bütün olarak değil, yavaş yavaş ve parça parça yapılan","e1":"Changes were made piecemeal.","e1t":"Değişiklikler parça parça yapıldı.","e2":"A piecemeal approach.","e2t":"Bölük pörçük bir yaklaşım."},{"w":"pied","tr":"alaca / çok renkli","te":"Adjective","tt":"Sıfat","de":"Having two or more colors in patches","dt":"Yamalar halinde iki veya daha fazla rengi olan","e1":"A pied wagtail (bird).","e1t":"Alaca kuyruksallayan.","e2":"The Pied Piper of Hamelin.","e2t":"Fareli Köyün Kavalcısı (Alaca giysili çalgıcı)."},{"w":"pigment","tr":"boya maddesi / pigment","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance that gives something its color","dt":"Bir şeye rengini veren madde","e1":"Melanin is the pigment that colors our skin.","e1t":"Melanin, cildimize renk veren pigmenttir.","e2":"Natural pigments.","e2t":"Doğal boya maddeleri."},{"w":"pillage","tr":"yağmalamak / çapulculuk etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To steal something from a place by force, especially during war","dt":"Bir yeri (özellikle savaşta) zorla yağmalamak","e1":"The city was pillaged by the invaders.","e1t":"Şehir istilacılar tarafından yağmalandı.","e2":"To pillage and burn.","e2t":"Yağmalamak ve yakmak."},{"w":"pillory","tr":"teşhir etmek / rezil etmek / boyunduruk","te":"Verb/Noun","tt":"Fiil/İsim","de":"To criticize someone strongly in public","dt":"Birini toplum önünde şiddetle eleştirmek (rezil etmek)","e1":"He was pillored by the press.","e1t":"Basın tarafından teşhir edildi (yerden yere vuruldu).","e2":"(Tarihi olarak suçlunun kafasının sokulduğu tahta düzenek).","e2t":""},{"w":"pion / pawn","tr":"piyon / kukla","te":"Noun","tt":"İsim","de":"A person used by others for their own purposes; or a chess piece","dt":"Başkalarının amaçları için kullanılan kişi; veya satranç taşı","e1":"He was just a pawn in their game.","e1t":"O sadece onların oyununda bir piyondur.","e2":"To sacrifice a pawn.","e2t":"Bir piyonu feda etmek."},{"w":"piquant","tr":"keskin (tat) / iştah açıcı / heyecan verici","te":"Adjective","tt":"Sıfat","de":"Having a pleasantly sharp or spicy taste; or interesting","dt":"Hoş, keskin veya baharatlı bir tadı olan; veya ilgi çekici","e1":"A piquant sauce.","e1t":"İştah açıcı (keskin) bir sos.","e2":"A piquant story.","e2t":"Heyecan verici (baharatlı) bir hikaye."},{"w":"pique","tr":"incinmek / merak uyandırmak / gücenme","te":"Verb/Noun","tt":"Fiil/İsim","de":"To excite interest; or to make someone annoyed","dt":"Merak uyandırmak; veya birini sinirlendirmek","e1":"The title of the book piqued my curiosity.","e1t":"Kitabın adı merakımı uyandırdı.","e2":"He left in a fit of pique (annoyance).","e2t":"Bir anlık gücenme (kızgınlık) ile ayrıldı."},{"w":"pith","tr":"öz / esas / ilik (bitki)","te":"Noun","tt":"İsim","de":"The essential part of something; or the white substance in fruit","dt":"Bir şeyin özü/esası; veya meyvedeki beyaz lifli tabaka","e1":"The pith of the argument.","e1t":"İddianın özü.","e2":"To get to the pith of the matter.","e2t":"Meselenin özüne inmek."},{"w":"pithy","tr":"özlü / kısa ve anlamlı","te":"Adjective","tt":"Sıfat","de":"(Of writing/speech) short but expressing important ideas clearly","dt":"(Yazı/konuşma için) kısa ama önemli fikirleri net ifade eden","e1":"A pithy comment.","e1t":"Özlü (kısa ve öz) bir yorum.","e2":"Pithy sayings.","e2t":"Vecizeler (özlü sözler)."},{"w":"pittance","tr":"sadaka / cüzi miktar / üç kuruş","te":"Noun","tt":"İsim","de":"A very small amount of money, especially as a wage","dt":"Özellikle ücret olarak ödenen, çok az miktar para","e1":"He works hard for a mere pittance.","e1t":"Bir hiç uğruna (üç kuruşa) çok sıkı çalışıyor.","e2":"To be paid a pittance.","e2t":"Sembolik bir ücret almak."},{"w":"placate","tr":"yatıştırmak / sakinleştirmek / gönlünü almak","te":"Verb","tt":"Fiil","de":"To stop someone from being angry by giving them what they want","dt":"İstediğini vererek birinin öfkesini dindirmek","e1":"Outraged customers were placated by offers of compensation.","e1t":"Öfkeli müşteriler tazminat teklifleriyle yatıştırıldı.","e2":"To placate an angry child.","e2t":"Kızgın bir çocuğun gönlünü almak."},{"w":"placebo","tr":"plasebo / yalancı ilaç","te":"Noun","tt":"İsim","de":"A substance given to a patient that has no physical effect","dt":"Hastaya verilen, fiziksel etkisi olmayan madde","e1":"The placebo effect.","e1t":"Plasebo etkisi.","e2":"Half of the group was given a placebo.","e2t":"Grubun yarısına plasebo verildi."},{"w":"placid","tr":"sakin / dingin / uysal","te":"Adjective","tt":"Sıfat","de":"Having a calm appearance or nature; not easily excited","dt":"Sakin görünümlü veya doğalı; kolay heyecanlanmayan","e1":"A placid lake.","e1t":"Dingin bir göl.","e2":"A slow","e2t":"moving and placid river."},{"w":"plagiarism","tr":"intihal / eser hırsızlığı","te":"Noun","tt":"İsim","de":"The practice of using someone else's work as your own","dt":"Başkasının eserini kendininmiş gibi kullanma pratiği","e1":"He was accused of plagiarism.","e1t":"İntihal yapmakla suçlandı.","e2":"To detect plagiarism in an essay.","e2t":"Bir makalede intihal tespit etmek."},{"w":"plaintive","tr":"hüzünlü / dertli / acıklı","te":"Adjective","tt":"Sıfat","de":"(Of a sound) used to describe something that sounds sad","dt":"(Ses için) üzgün veya acıklı gelen","e1":"A plaintive cry for help.","e1t":"Acıklı bir yardım çığlığı.","e2":"The plaintive sound of a lone flute.","e2t":"Yalnız bir flütün hüzünlü sesi."},{"w":"plasticity","tr":"şekil alabilirlik / esneklik / plastisite","te":"Noun","tt":"İsim","de":"The quality of being easily shaped or molded","dt":"Kolayca şekillendirilebilme niteliği","e1":"The plasticity of clay.","e1t":"Kilin şekil alabilirliği.","e2":"Brain plasticity (neuroplasticity).","e2t":"Beyin plastisitesi (öğrenme yeteneği)."},{"w":"platitude","tr":"basmakalıp söz / klişe / beylik laf","te":"Noun","tt":"İsim","de":"A remark or statement that has been used too often to be interesting","dt":"İlgi çekici olmayacak kadar sık kullanılmış söz","e1":"His speech was full of empty platitudes.","e1t":"Konuşması boş klişelerle doluydu.","e2":"To mouth platitudes about world peace.","e2t":"Dünya barışı hakkında basmakalıp laflar etmek."},{"w":"platonic","tr":"platonik / dostça (cinsellik içermeyen)","te":"Adjective","tt":"Sıfat","de":"(Of a relationship) affectionate but not sexual","dt":"Sevgi dolu ama cinsel olmayan (ilişki)","e1":"Their relationship is purely platonic.","e1t":"İlişkileri tamamen dostça (platonik).","e2":"Platonic love.","e2t":"Platonik aşk."},{"w":"plaudit","tr":"alkış / övgü / takdir","te":"Noun","tt":"İsim","de":"Praise or approval from many people (usually plural)","dt":"Birçok insandan gelen övgü veya onay","e1":"The film has won plaudits from critics.","e1t":"Film, eleştirmenlerden büyük takdir (alkış) topladı.","e2":"She received the plaudits of the crowd.","e2t":"Kalabalığın alkışlarını aldı."},{"w":"plebeian","tr":"halka ait / avam / kaba","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the lower social classes; or not educated","dt":"Alt sosyal sınıflara ait; veya eğitimsiz/kaba","e1":"Plebeian tastes.","e1t":"Halk işi (avam) zevkler.","e2":"To have a plebeian background.","e2t":"Halktan (sıradan) bir geçmişe sahip olmak."},{"w":"plenary","tr":"tam / bütün / genel (kurul)","te":"Adjective","tt":"Sıfat","de":"(Of a meeting) attended by all participants; or complete","dt":"(Toplantı için) tüm katılımcıların hazır bulunduğu; veya tam","e1":"A plenary session of Congress.","e1t":"Kongre'nin genel kurulu (tam oturumu).","e2":"To have plenary powers.","e2t":"Tam yetkiye sahip olmak."},{"w":"plenitude","tr":"bolluk / çokluk / tamlık","te":"Noun","tt":"İsim","de":"A large amount of something; or the state of being full","dt":"Bir şeyin büyük miktarı; veya tam olma durumu","e1":"A plenitude of resources.","e1t":"Kaynak bolluğu.","e2":"The plenitude of his power.","e2t":"Gücünün tamlığı (mutlaklığı)."},{"w":"plethora","tr":"bolluk / gereğinden fazla / çokluk","te":"Noun","tt":"İsim","de":"A very large amount of something, especially more than you need","dt":"Bir şeyin, özellikle ihtiyaçtan fazlasının çok büyük miktarı","e1":"A plethora of suggestions.","e1t":"Öneri çokluğu (yığını).","e2":"We are facing a plethora of problems.","e2t":"Bir yığın sorunla karşı karşıyayız."},{"w":"pliable","tr":"esnek / uysal / bükülebilir","te":"Adjective","tt":"Sıfat","de":"Easily bent without breaking; or easily influenced","dt":"Kırılmadan kolayca bükülebilen; veya kolayca etkilenen","e1":"Pliable leather.","e1t":"Yumuşak (esnek) deri.","e2":"He has a very pliable nature.","e2t":"Çok uysal (kolay yönlendirilen) bir doğası var."},{"w":"pliant","tr":"uysal / esnek / yumuşak","te":"Adjective","tt":"Sıfat","de":"Easily influenced or controlled; or easily bent","dt":"Kolayca etkilenen veya kontrol edilen; veya kolayca bükülen","e1":"A pliant personality.","e1t":"Uysal bir kişilik.","e2":"The pliant branches of the willow.","e2t":"Söğüt ağacının esnek dalları."},{"w":"ploy","tr":"taktik / oyun / hile","te":"Noun","tt":"İsim","de":"A clever plan or action used to get an advantage","dt":"Avantaj elde etmek için kullanılan zeki plan veya eylem","e1":"A marketing ploy.","e1t":"Pazarlama taktiği (oyunu).","e2":"It was all a clever ploy to get me to stay.","e2t":"Hepsi kalmamı sağlamak için yapılmış zekice bir hileydi."},{"w":"plumage","tr":"kuş tüyleri","te":"Noun","tt":"İsim","de":"A bird's feathers collectively","dt":"Bir kuşun tüylerinin tamamı","e1":"Brightly colored plumage.","e1t":"Parlak renkli kuş tüyleri.","e2":"To display one's plumage.","e2t":"Tüylerini sergilemek."},{"w":"plumb","tr":"derinliğini ölçmek / araştırmak / dik (kurşun kalem)","te":"Verb/Noun/Adv","tt":"To measure the depth of water; or to explore in detail","de":"Suyun derinliğini ölçmek; veya detaylıca araştırmak","dt":"To plumb the depths of the ocean.","e1":"Okyanusun derinliklerini ölçmek.","e1t":"A book that plumbs the mysteries of the mind.","e2":"Zihnin gizemlerini araştıran bir kitap.","e2t":""},{"w":"plummet","tr":"çakılmak / aniden düşmek / dikey inmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To fall very quickly and suddenly","dt":"Çok hızlı ve aniden düşmek","e1":"Share prices plummeted.","e1t":"Hisse fiyatları çakıldı (aniden düştü).","e2":"Temperatures are expected to plummet tonight.","e2t":"Sıcaklıkların bu gece aniden düşmesi bekleniyor."},{"w":"plutocracy","tr":"zenginler yönetimi / plutokrasi","te":"Noun","tt":"İsim","de":"A country or society that is governed by the wealthy","dt":"Zenginler tarafından yönetilen ülke veya toplum","e1":"To live in a plutocracy.","e1t":"Bir plutokraside yaşamak.","e2":"The rising power of the plutocracy.","e2t":"Zenginler sınıfının artan gücü."},{"w":"podium","tr":"kürsü / podyum / platform","te":"Noun","tt":"İsim","de":"A small platform on which a person stands to give a speech","dt":"Birinin konuşma yapmak için üzerine çıktığı küçük platform","e1":"To stand on the podium.","e1t":"Kürsüye çıkmak.","e2":"The winner stood on the podium to receive the medal.","e2t":"Kazanan, madalyayı almak için podyuma çıktı."},{"w":"poignancy","tr":"dokunaklılık / yürek yakıcılık","te":"Noun","tt":"İsim","de":"The quality of being very sad or making you feel sad","dt":"Çok üzücü olma veya üzüntü verme niteliği","e1":"The poignancy of the final scene.","e1t":"Final sahnesinin dokunaklılığı.","e2":"The moment had a special poignancy.","e2t":"Anın özel bir yürek yakıcılığı vardı."},{"w":"polarize / polarise","tr":"kutuplaştırmak / uçlara ayırmak / polarize etmek","te":"Verb","tt":"Fiil","de":"To cause people to divide into two opposing groups","dt":"İnsanların iki zıt gruba ayrılmasına neden olmak","e1":"The issue has polarized public opinion.","e1t":"Konu, kamuoyunu kutuplaştırdı.","e2":"Polarized lenses.","e2t":"Polarize camlar."},{"w":"polemic","tr":"tartışma / sert eleştiri / polemik","te":"Noun","tt":"İsim","de":"A strong attack on or defense of an opinion or person","dt":"Bir görüşe veya kişiye yönelik sert saldırı veya savunma","e1":"A fierce polemic against the government.","e1t":"Hükümete karşı şiddetli bir polemik.","e2":"Polemical writing.","e2t":"Tartışmacı (eleştirel) yazı."},{"w":"politic","tr":"politik / akıllıca / yerinde / kurnaz","te":"Adjective","tt":"Sıfat","de":"(Of an action) wise and showing good judgment","dt":"(Eylem için) akıllıca ve sağduyulu","e1":"It would not be politic to ignore them.","e1t":"Onları görmezden gelmek akıllıca olmazdı.","e2":"A politic decision.","e2t":"Yerinde (mantıklı) bir karar."},{"w":"polity","tr":"yönetim biçimi / siyasi topluluk / devlet","te":"Noun","tt":"İsim","de":"A particular form of government or a politically organized society","dt":"Belirli bir hükümet biçimi veya siyasi olarak örgütlenmiş toplum","e1":"The democratic polity.","e1t":"Demokratik yönetim biçimi.","e2":"A complex polity.","e2t":"Karmaşık bir siyasi yapı."},{"w":"polygamist","tr":"çok eşli / poligamist","te":"Noun","tt":"İsim","de":"A person who has more than one wife or husband at the same time","dt":"Aynı anda birden fazla eşi olan kişi","e1":"To live as a polygamist.","e1t":"Çok eşli olarak yaşamak.","e2":"(Not: Erkek için polygyny, kadın için polyandry terimleri de kullanılır).","e2t":""},{"w":"ponderous","tr":"hantal / ağır / sıkıcı","te":"Adjective","tt":"Sıfat","de":"Slow and awkward because of being very heavy or boring","dt":"Çok ağır olduğu için yavaş/beceriksiz veya sıkıcı","e1":"A ponderous writing style.","e1t":"Ağır (sıkıcı) bir yazı tarzı.","e2":"Ponderous movements.","e2t":"Hantal hareketler."},{"w":"pontifical","tr":"papa ile ilgili / kibirli / kesin konuşan","te":"Adjective","tt":"Sıfat","de":"Relating to the Pope; or speaking as if you are always right","dt":"Papa ile ilgili; veya her zaman haklıymış gibi konuşan","e1":"Pontifical vestments.","e1t":"Papa kıyafetleri.","e2":"He can be very pontifical at times.","e2t":"Bazen çok bilmiş (kesin konuşan) olabilir."},{"w":"porous","tr":"gözenekli / süzgeç gibi / geçirgen","te":"Adjective","tt":"Sıfat","de":"Having many small holes through which air or water can pass","dt":"İçinden hava veya suyun geçebileceği çok sayıda küçük deliği olan","e1":"Porous rock.","e1t":"Gözenekli kaya.","e2":"Porous boundaries (easy to cross).","e2t":"Geçirgen (kolay aşılabilen) sınırlar."},{"w":"portend","tr":"işaret etmek / alameti olmak / önceden haber vermek","te":"Verb","tt":"Fiil","de":"To be a sign that something bad is likely to happen (formal)","dt":"Kötü bir şeyin gerçekleşeceğinin işareti olmak (resmi)","e1":"Dark clouds that portend a storm.","e1t":"Fırtınaya işaret eden koyu bulutlar.","e2":"The event portends a major change.","e2t":"Olay büyük bir değişimi haber veriyor."},{"w":"portent","tr":"alamet / belirti / işaret","te":"Noun","tt":"İsim","de":"A sign or warning of something that is going to happen","dt":"Gelecek bir şeyin işareti veya uyarısı","e1":"A portent of disaster.","e1t":"Felaket alameti.","e2":"I hope it is not a bad portent.","e2t":"Umarım kötü bir işaret değildir."},{"w":"portly","tr":"iri yarı / kilolu / heybetli","te":"Adjective","tt":"Sıfat","de":"Fat and round (usually used of an older man in a polite way)","dt":"Kilolu ve yuvarlak hatlı (genellikle yaşlı erkekler için nazikçe kullanılır)","e1":"A portly gentleman.","e1t":"İri yarı (heybetli) bir beyefendi.","e2":"He had become rather portly.","e2t":"Oldukça göbekli (iri) biri olmuştu."},{"w":"poseur","tr":"yapmacık tavırlı / pozcu","te":"Noun","tt":"İsim","de":"A person who behaves in a way that is intended to impress others","dt":"Başkalarını etkilemek için yapmacık davranan kişi","e1":"He's just a poseur.","e1t":"O sadece bir pozcu (yapmacık biri).","e2":"A social poseur.","e2t":"Sosyal ortamlarda rol yapan biri."},{"w":"posthumous","tr":"ölümden sonra / babası öldükten sonra doğan","te":"Adjective","tt":"Sıfat","de":"Happening or given after a person's death","dt":"Bir kişinin ölümünden sonra gerçekleşen veya verilen","e1":"A posthumous award.","e1t":"Ölümünden sonra verilen ödül.","e2":"The posthumous publication of his last book.","e2t":"Son kitabının ölümünden sonra basılması."},{"w":"postulate","tr":"varsaymak / ileri sürmek / aksiyom","te":"Verb/Noun","tt":"Fiil/İsim","de":"To suggest that something is true or useful (formal)","dt":"Bir şeyin doğru veya faydalı olduğunu ileri sürmek (resmi)","e1":"He postulated that the universe is expanding.","e1t":"Evrenin genişlediğini varsaydı (ileri sürdü).","e2":"A basic postulate of the theory.","e2t":"Teorinin temel varsayımı."},{"w":"potable","tr":"içilebilir","te":"Adjective","tt":"Sıfat","de":"(Of water) safe to drink","dt":"(Su için) içilmesi güvenli","e1":"Potable water.","e1t":"İçilebilir su.","e2":"To ensure the water is potable.","e2t":"Suyun içilebilir olduğundan emin olmak."},{"w":"potentate","tr":"hükümdar / nüfuzlu kişi","te":"Noun","tt":"İsim","de":"A powerful ruler, especially one who is not limited by a parliament","dt":"Güçlü bir yönetici, özellikle yetkileri sınırlanmamış olan","e1":"A local potentate.","e1t":"Yerel bir nüfuzlu kişi.","e2":"The absolute potentates of the past.","e2t":"Geçmişin mutlak hükümdarları."},{"w":"potion","tr":"iksir / tıbbi içki","te":"Noun","tt":"İsim","de":"A liquid with magical or medicinal powers","dt":"Sihirli veya tıbbi güçleri olan sıvı","e1":"A magic potion.","e1t":"Sihirli iksir.","e2":"A love potion.","e2t":"Aşk iksiri."},{"w":"potpourri","tr":"potpuri / karışım","te":"Noun","tt":"İsim","de":"A mixture of dried flowers to make a room smell pleasant; or a mix","dt":"Odanın hoş kokması için kurutulmuş çiçek karışımı; veya karma","e1":"A potpourri of musical styles.","e1t":"Müzik tarzları potpurisi (karışımı).","e2":"A bowl of potpourri.","e2t":"Bir kase hoş kokulu kuru çiçek."},{"w":"practicable","tr":"uygulanabilir / yapılabilir","te":"Adjective","tt":"Sıfat","de":"Able to be done or put into action successfully","dt":"Başarıyla yapılabilen veya uygulamaya konulabilen","e1":"A practicable plan.","e1t":"Uygulanabilir bir plan.","e2":"It is not practicable to do it that way.","e2t":"Onu bu şekilde yapmak mümkün (pratik) değil."},{"w":"pragmatic","tr":"faydacı / pragmatik / gerçekçi","te":"Adjective","tt":"Sıfat","de":"Dealing with problems in a practical way rather than with theories","dt":"Sorunları teorilerle değil, pratik ve gerçekçi yollarla ele alan","e1":"A pragmatic approach to management.","e1t":"Yönetime faydacı (gerçekçi) bir yaklaşım.","e2":"He is very pragmatic.","e2t":"O çok gerçekçidir."},{"w":"pragmatist","tr":"pragmatist / faydacı kişi","te":"Noun","tt":"İsim","de":"A person who is guided more by practical considerations than by ideals","dt":"İdeallerden ziyade pratik düşüncelerle hareket eden kişi","e1":"As a pragmatist, he was willing to compromise.","e1t":"Bir pragmatist olarak uzlaşmaya hazırdı.","e2":"Political pragmatists.","e2t":"Siyasi faydacılar."},{"w":"prate","tr":"gevezelik etmek / boş konuşmak","te":"Verb","tt":"Fiil","de":"To talk foolishly or at tedious length about something","dt":"Bir şey hakkında aptalca veya bıktıracak kadar uzun konuşmak","e1":"To prate on about one's achievements.","e1t":"Başarıları hakkında boş boş (gevezelik ederek) konuşmak.","e2":"","e2t":""},{"w":"prattle","tr":"boş konuşmak / çocuksu konuşmak / lakırdı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To talk in a silly way or like a child for a long time","dt":"Uzun süre çocuk gibi veya saçma sapan konuşmak","e1":"She prattled on about her new dress.","e1t":"Yeni elbisesi hakkında boş boş (durmadan) konuştu.","e2":"Childish prattle.","e2t":"Çocukça lakırdı."},{"w":"preamble","tr":"giriş / önsöz / başlangıç","te":"Noun","tt":"İsim","de":"An introduction to a formal document or a speech","dt":"Resmi bir belgenin veya konuşmanın girişi","e1":"The preamble to the Constitution.","e1t":"Anayasa'nın başlangıç (başlangıç metni) kısmı.","e2":"Without any preamble.","e2t":"Hiç lafı uzatmadan (giriş yapmadan)."},{"w":"precept","tr":"kural / ilke / düstur","te":"Noun","tt":"Isim","de":"A rule for action or behavior","dt":"Hareket veya davranış kuralı","e1":"A moral precept.","e1t":"Ahlaki bir ilke.","e2":"To follow the precepts of one's religion.","e2t":"Dininin kurallarına (düsturlarına) uymak."},{"w":"precinct","tr":"bölge / alan / polis mıntıkası","te":"Noun","tt":"İsim","de":"An area in a city that has a particular use or is closed to cars","dt":"Şehirde belirli bir kullanımı olan veya trafiğe kapalı alan","e1":"A shopping precinct.","e1t":"Alışveriş bölgesi.","e2":"Within the precincts of the cathedral.","e2t":"Katedralin sınırları (alanı) içinde."},{"w":"precipice","tr":"uçurum / sarp kayalık / tehlikeli durum","te":"Noun","tt":"İsim","de":"A very steep side of a high cliff","dt":"Yüksek bir kayalığın çok dik tarafı","e1":"To stand on the edge of a precipice.","e1t":"Bir uçurumun kenarında durmak.","e2":"On the precipice of war.","e2t":"Savaşın eşiğinde (uçurumunda)."},{"w":"precipitous","tr":"dik / sarp / ani ve hızlı","te":"Adjective","tt":"Sıfat","de":"Very steep; or (of a change) sudden and great","dt":"Çok dik; veya (değişim için) ani ve çok büyük","e1":"A precipitous mountain path.","e1t":"Sarp bir dağ yolu.","e2":"A precipitous drop in profits.","e2t":"Kârlarda ani ve sert bir düşüş."},{"w":"précis","tr":"özet / hülsa","te":"Noun","tt":"İsim","de":"A short summary of a speech or piece of writing","dt":"Bir konuşma veya yazının kısa özeti","e1":"To write a précis of the report.","e1t":"Raporun bir özetini çıkarmak.","e2":"A clear and concise précis.","e2t":"Net ve özlü bir özet."},{"w":"preclude","tr":"önlemek / engel olmak / imkansız kılmak","te":"Verb","tt":"Fiil","de":"To prevent something or make it impossible","dt":"Bir şeyi önlemek veya imkansız hale getirmek","e1":"His contract precludes him from working for a rival.","e1t":"Sözleşmesi onun bir rakip için çalışmasını engelliyor.","e2":"To preclude any possibility of error.","e2t":"Her türlü hata ihtimalini ortadan kaldırmak."},{"w":"precocious","tr":"erken gelişmiş / büyümüş de küçülmüş","te":"Adjective","tt":"Sıfat","de":"(Of a child) showing mental development earlier than usual","dt":"(Çocuk için) normalden erken zihinsel gelişim gösteren","e1":"A precocious child who could read at three.","e1t":"Üç yaşında okuyabilen erken gelişmiş bir çocuk.","e2":"Precocious talent.","e2t":"Erken gelişmiş yetenek."},{"w":"precursor","tr":"öncü / müjdeci / belirti","te":"Noun","tt":"İsim","de":"Something that happened or existed before another thing","dt":"Başka bir şeyden önce gelen veya onun habercisi olan şey","e1":"A precursor to the modern computer.","e1t":"Modern bilgisayarın öncüsü.","e2":"These events were a precursor to the revolution.","e2t":"Bu olaylar devrimin habercisiydi."},{"w":"predetermine","tr":"önceden belirlemek / kararlaştırmak","te":"Verb","tt":"Fiil","de":"To decide or arrange something at an earlier time","dt":"Bir şeyi daha önceki bir zamanda kararlaştırmak","e1":"The outcome was predetermined.","e1t":"Sonuç önceden belliydi.","e2":"Predetermined rules.","e2t":"Önceden belirlenmiş kurallar."},{"w":"predilection","tr":"eğilim / düşkünlük / tercih","te":"Noun","tt":"İsim","de":"A strong liking or preference for something","dt":"Bir şeye duyulan güçlü ilgi veya tercih","e1":"A predilection for spicy food.","e1t":"Baharatlı yemeğe duyulan düşkünlük.","e2":"To have a predilection for art.","e2t":"Sanata karşı bir eğilimi olmak."},{"w":"predispose","tr":"yatkınlaştırmak / önceden hazırlamak","te":"Verb","tt":"Fiil","de":"To make someone more likely to behave in a particular way","dt":"Birini belirli bir şekilde davranmaya daha yatkın hale getirmek","e1":"Smoking predisposes you to lung cancer.","e1t":"Sigara içmek sizi akciğer kanserine yatkınlaştırır.","e2":"To be predisposed to believe something.","e2t":"Bir şeye inanmaya meyilli olmak."},{"w":"preeminent / pre","tr":"eminent","te":"üstün / seçkin / önde gelen","tt":"Adjective","de":"Sıfat","dt":"More important or powerful than others","e1":"Diğerlerinden daha önemli veya güçlü","e1t":"The preeminent scientist of his day.","e2":"Döneminin en önde gelen bilim insanı.","e2t":"A preeminent position."},{"w":"preempt / pre","tr":"empt","te":"önceden davranmak / engellemek / yerini almak","tt":"Verb","de":"Fiil","dt":"To do something before someone else to prevent them","e1":"Başkasından önce davranarak onu engellemek","e1t":"To preempt a question.","e2":"(Sorulmadan önce cevaplayarak) bir sorunun önünü kesmek.","e2t":"The news program was preempted by a special report."},{"w":"preen","tr":"kendine çeki düzen vermek / (kuş) tüylerini düzeltmek","te":"Verb","tt":"Fiil","de":"(Of a bird) to clean feathers with its beak; or to spend time making yourself look attractive","dt":"(Kuş için) tüylerini gagasıyla temizlemek; veya süslenmek","e1":"The swan was preening its feathers.","e1t":"Kuğu tüylerini düzeltiyordu.","e2":"He preened himself in front of the mirror.","e2t":"Aynanın karşısında kendine çeki düzen verdi (süslendi)."},{"w":"prehensile","tr":"kavrayıcı / tutucu","te":"Adjective","tt":"Sıfat","de":"(Of a body part) able to hold on to things","dt":"(Vücut parçası için) nesneleri tutabilen","e1":"A monkey's prehensile tail.","e1t":"Bir maymunun kavrayıcı (tutucu) kuyruğu.","e2":"Prehensile limbs.","e2t":"Kavrayıcı uzuvlar."},{"w":"prelate","tr":"yüksek rütbeli din adamı","te":"Noun","tt":"İsim","de":"An important priest of high rank","dt":"Yüksek rütbeli, önemli din adamı","e1":"A gathering of prelates.","e1t":"Yüksek rütbeli din adamlarının buluşması.","e2":"The court prelate.","e2t":"Saray rahibi."},{"w":"prelude","tr":"başlangıç / hazırlık / uvertür","te":"Noun/Verb","tt":"İsim/Fiil","de":"Something that comes before a more important event","dt":"Daha önemli bir olaydan önce gelen şey","e1":"The changes were a prelude to the war.","e1t":"Değişiklikler savaşın bir başlangıcıydı (habercisiydi).","e2":"A musical prelude.","e2t":"Müzikal başlangıç (prelüd)."},{"w":"premeditate","tr":"önceden tasarlamak / kasten yapmak","te":"Verb","tt":"Fiil","de":"To plan a crime or bad action before doing it","dt":"Bir suçu veya kötü eylemi yapmadan önce planlamak","e1":"Premeditated murder.","e1t":"Taammüden (kasten/tasarlanmış) cinayet.","e2":"A premeditated attack.","e2t":"Önceden planlanmış saldırı."},{"w":"premonition","tr":"içine doğma / önsezi / kötü his","te":"Noun","tt":"İsim","de":"A feeling that something, especially something unpleasant, is going to happen","dt":"Özellikle nahoş bir şeyin olacağına dair his","e1":"He had a premonition of disaster.","e1t":"İçine bir felaket doğdu (felaketi önceden hissetti).","e2":"A strange premonition.","e2t":"Tuhaf bir önsezi."},{"w":"preponderance","tr":"çoğunluk / baskınlık / üstünlük","te":"Noun","tt":"İsim","de":"The fact of being larger in number or importance","dt":"Sayıca veya önemce daha fazla (baskın) olma durumu","e1":"A preponderance of evidence.","e1t":"Kanıtların çokluğu (üstünlüğü).","e2":"The preponderance of women in the teaching profession.","e2t":"Öğretmenlik mesleğinde kadınların çoğunlukta olması."},{"w":"presage","tr":"kehanette bulunmak / belirtisi olmak / alamet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To be a sign that something will happen (formal)","dt":"Bir şeyin olacağının işareti olmak (resmi)","e1":"The clouds presaged a storm.","e1t":"Bulutlar fırtınanın habercisiydi.","e2":"A presage of doom.","e2t":"Felaket alameti."},{"w":"prescience","tr":"öngörü / ileriyi görme","te":"Noun","tt":"İsim","de":"The ability to know or imagine what will happen in the future","dt":"Gelecekte ne olacağını bilme veya tahmin etme yeteneği","e1":"He predicted the crisis with amazing prescience.","e1t":"Krizi şaşırtıcı bir öngörüyle tahmin etti.","e2":"Prescient (adjective).","e2t":"Öngörülü."},{"w":"presentiment","tr":"önsezi / içine doğma","te":"Noun","tt":"İsim","de":"A feeling that something, especially something unpleasant, is about to happen (formal)","dt":"Özellikle kötü bir şeyin olmak üzere olduğuna dair his (resmi)","e1":"A presentiment of disaster.","e1t":"Bir felaket önsezisi.","e2":"To have a sudden presentiment.","e2t":"Aniden bir şeyi önceden hissetmek."},{"w":"presumptuous","tr":"küstah / cüretkâr / haddini bilmez","te":"Adjective","tt":"Sıfat","de":"Showing too much confidence and not enough respect","dt":"Aşırı güvenli ve saygısızca davranan","e1":"It would be presumptuous of me to give you advice.","e1t":"Size tavsiye vermek benim haddimi aşmak (küstahlık) olurdu.","e2":"A presumptuous young man.","e2t":"Haddini bilmez genç bir adam."},{"w":"pretentious","tr":"gösterişçi / yapmacık / iddialı","te":"Adjective","tt":"Sıfat","de":"Trying to appear more important or intelligent than you are","dt":"Olduğundan daha önemli veya zeki görünmeye çalışan","e1":"A pretentious restaurant.","e1t":"Gösterişli (yapmacık) bir restoran.","e2":"His writing is very pretentious.","e2t":"Yazıları çok yapmacık (iddialı)."},{"w":"preternatural","tr":"doğaüstü / olağanüstü / gizemli","te":"Adjective","tt":"Sıfat","de":"Beyond what is normal or natural","dt":"Normal veya doğal olanın ötesinde","e1":"A preternatural ability.","e1t":"Olağanüstü bir yetenek.","e2":"A preternatural silence.","e2t":"Gizemli (doğaüstü gibi) bir sessizlik."},{"w":"prevaricate","tr":"kaçamak konuşmak / lafı dolandırmak","te":"Verb","tt":"Fiil","de":"To avoid telling the truth by not answering a question directly","dt":"Soruyu doğrudan cevaplamayarak gerçeği söylemekten kaçınmak","e1":"Stop prevaricating and tell me the truth!","e1t":"Lafı dolandırmayı bırak da bana gerçeği söyle!","e2":"To prevaricate in court.","e2t":"Mahkemede kaçamak cevaplar vermek."},{"w":"prim","tr":"aşırı ciddi / kuralcı / titiz / derli toplu","te":"Adjective","tt":"Sıfat","de":"Very formal and correct and easily shocked","dt":"Çok resmi, kuralcı ve kolayca şoke olan","e1":"She is very prim and proper.","e1t":"Çok hanım hanımcık (kuralcı ve ciddi).","e2":"A prim suit.","e2t":"Derli toplu (resmi) bir takım elbise."},{"w":"primal","tr":"ilkel / temel / asıl","te":"Adjective","tt":"Sıfat","de":"Basic and relating to the earliest stage of development","dt":"Temel ve gelişimin en erken aşamasıyla ilgili","e1":"Primal fears.","e1t":"İlkel korkular.","e2":"The primal cause.","e2t":"Temel (asıl) neden."},{"w":"primate","tr":"başpiskopos / primat (memeli takımı)","te":"Noun","tt":"İsim","de":"A member of the group of mammals including humans and monkeys; or a high priest","dt":"İnsan ve maymunları içeren memeli grubu; veya başpiskopos","e1":"Monkeys are primates.","e1t":"Maymunlar primattır.","e2":"The Primate of all England.","e2t":"Tüm İngiltere'nin Başpiskoposu."},{"w":"primeval / primaeval","tr":"ilk çağlara ait / kadim / ilkel","te":"Adjective","tt":"Sıfat","de":"Relating to the earliest times in the history of the world","dt":"Dünya tarihinin en erken dönemlerine ait","e1":"Primeval forests.","e1t":"Balta girmemiş (kadim) ormanlar.","e2":"Primeval instincts.","e2t":"İlk çağlardan kalma (ilkel) içgüdüler."},{"w":"primordial","tr":"başlangıçtaki / ezeli / ilkel","te":"Adjective","tt":"Sıfat","de":"Existing at or from the beginning of time","dt":"Zamanın başlangıcından beri var olan","e1":"The primordial soup (origin of life).","e1t":"İlkel çorba (hayatın başlangıcı).","e2":"Primordial cells.","e2t":"İlk (ilkel) hücreler."},{"w":"pristine","tr":"bozulmamış / tertemiz / ilk günkü gibi","te":"Adjective","tt":"Sıfat","de":"In its original condition; unspoiled","dt":"Orijinal durumunda; bozulmamış","e1":"Pristine beaches.","e1t":"El değmemiş (tertemiz) plajlar.","e2":"The car is in pristine condition.","e2t":"Araba ilk günkü gibi (kusursuz) durumda."},{"w":"privation","tr":"yoksunluk / darlık / mahrumiyet","te":"Noun","tt":"İsim","de":"A lack of the basic things that are necessary for life","dt":"Yaşam için gerekli temel şeylerin eksikliği","e1":"Years of war and privation.","e1t":"Savaş ve mahrumiyetle geçen yıllar.","e2":"To suffer great privation.","e2t":"Büyük yoksunluk çekmek."},{"w":"probity","tr":"dürüstlük / doğruluk / namus","te":"Noun","tt":"İsim","de":"Complete honesty (formal)","dt":"Tam dürüstlük (resmi)","e1":"A person of undisputed probity.","e1t":"Dürüstlüğü tartışılmaz bir kişi.","e2":"Financial probity.","e2t":"Finansal doğruluk/dürüstlük."},{"w":"problematic / problematical","tr":"sorunlu / tartışmalı / şüpheli","te":"Adjective","tt":"Sıfat","de":"Containing problems or difficult to deal with","dt":"Sorunlar içeren veya baş etmesi zor olan","e1":"The situation is highly problematic.","e1t":"Durum oldukça sorunlu.","e2":"A problematic assumption.","e2t":"Tartışmalı (şüpheli) bir varsayım."},{"w":"proclivity","tr":"eğilim / meyil / yatkınlık","te":"Noun","tt":"İsim","de":"A tendency to do or feel something, especially something bad","dt":"Bir şeyi yapma veya hissetme eğilimi (genellikle kötü bir şeye)","e1":"A proclivity for violence.","e1t":"Şiddete eğilim.","e2":"His proclivity to exaggerate.","e2t":"Onun mübalağa (abartma) yatkınlığı."},{"w":"prodigal","tr":"savurgan / müsrif / eli açık","te":"Adjective","tt":"Sıfat","de":"Spending money or using resources too freely","dt":"Parayı veya kaynakları çok serbestçe harcayan","e1":"The prodigal son.","e1t":"Savurgan (tövbe edip dönen) oğul.","e2":"Prodigal habits.","e2t":"Müsrif alışkanlıklar."},{"w":"prodigious","tr":"muazzam / devasa / şaşırtıcı","te":"Adjective","tt":"Sıfat","de":"Extremely great in ability, amount, or size","dt":"Yetenek, miktar veya boyut olarak son derece büyük","e1":"A prodigious memory.","e1t":"Muazzam bir hafıza.","e2":"He consumed a prodigious amount of food.","e2t":"Şaşırtıcı miktarda yemek yedi."},{"w":"profligate","tr":"müsrif / ahlaksız / savurgan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Spending money in a way that wastes it; or immoral","dt":"Parayı çarçur eden; veya ahlaksız","e1":"Profligate spending.","e1t":"Savurgan harcama.","e2":"A profligate lifestyle.","e2t":"Sefahat dolu (ahlaksız) bir yaşam tarzı."},{"w":"profusion","tr":"bolluk / çokluk / bereket","te":"Noun","tt":"İsim","de":"A very large amount of something","dt":"Bir şeyin çok büyük miktarı","e1":"A profusion of wild flowers.","e1t":"Yabani çiçek bolluğu.","e2":"The book was illustrated with a profusion of drawings.","e2t":"Kitap çok sayıda çizimle donatılmıştı."},{"w":"progenitor","tr":"ata / cet / kurucu","te":"Noun","tt":"İsim","de":"A person who first creates or develops something; or an ancestor","dt":"Bir şeyi ilk yaratan veya geliştiren kişi; veya ata","e1":"The progenitor of modern physics.","e1t":"Modern fiziğin kurucusu (atası).","e2":"His royal progenitors.","e2t":"Onun kraliyet soyundan gelen ataları."},{"w":"progeny","tr":"döl / evlat / soy / çocuklar","te":"Noun","tt":"İsim","de":"The young of a person, animal, or plant (formal)","dt":"Bir insanın, hayvanın veya bitkinin yavruları (resmi)","e1":"To produce numerous progeny.","e1t":"Çok sayıda döl (yavru) vermek.","e2":"They are the progeny of a famous artist.","e2t":"Ünlü bir sanatçının çocuklarıdırlar."},{"w":"prognosis","tr":"tahmin (hastalık) / gidişat tahmini","te":"Noun","tt":"İsim","de":"A doctor's judgment of the likely development of an illness","dt":"Bir hastalığın muhtemel seyri hakkındaki doktor tahmini","e1":"The prognosis for a full recovery is good.","e1t":"Tam iyileşme tahmini (prognoz) iyi.","e2":"An economic prognosis.","e2t":"Ekonomik gidişat tahmini."},{"w":"projectile","tr":"mermi / fırlatılan cisim","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An object that is thrown or shot forwards","dt":"İleriye doğru fırlatılan veya atılan nesne","e1":"The stones were used as projectiles.","e1t":"Taşlar fırlatılan cisimler (mermi) olarak kullanıldı.","e2":"Projectile motion (physics).","e2t":"Eğik atış (mermi) hareketi."},{"w":"proletarian","tr":"işçi sınıfı / proleter","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the working class","dt":"İşçi sınıfı ile ilgili","e1":"Proletarian literature.","e1t":"İşçi sınıfı edebiyatı.","e2":"Proletarian revolution.","e2t":"Proleter devrim."},{"w":"proliferate","tr":"çoğalmak / hızla artmak / üremek","te":"Verb","tt":"Fiil","de":"To increase a lot and suddenly in number","dt":"Sayıca aniden ve çok fazla artmak","e1":"Small businesses have proliferated in the last year.","e1t":"Son bir yılda küçük işletmeler hızla arttı (çoğaldı).","e2":"To proliferate nuclear weapons.","e2t":"Nükleer silahları yaymak."},{"w":"prolix","tr":"uzun ve sıkıcı / laf kalabalığı yapan","te":"Adjective","tt":"Sıfat","de":"(Of writing/speech) using too many words","dt":"(Yazı/konuşma için) çok fazla kelime kullanan (sıkıcı)","e1":"A prolix style of writing.","e1t":"Kelime kalabalığı içeren (sıkıcı) bir yazı tarzı.","e2":"He can be rather prolix.","e2t":"Oldukça lafazan olabilir."},{"w":"promiscuous","tr":"rastgele ilişki kuran / karışık / ayırt etmeyen","te":"Adjective","tt":"Sıfat","de":"Having a lot of different sexual partners; or not restricted","dt":"Çok sayıda farklı cinsel partneri olan; veya kısıtlanmamış/karışık","e1":"Promiscuous behavior.","e1t":"Rastgele cinsel ilişki davranışı.","e2":"A promiscuous reader (reading many types).","e2t":"Seçici olmayan (her şeyi okuyan) bir okuyucu."},{"w":"promontory","tr":"burun (coğrafya) / sarp çıkıntı","te":"Noun","tt":"İsim","de":"A narrow area of high land that sticks out into the sea","dt":"Denize doğru uzanan yüksek, dar kara alanı (burun)","e1":"A rocky promontory.","e1t":"Kayalık bir burun.","e2":"To look out from the promontory.","e2t":"Burundan dışarı bakmak."},{"w":"promulgate","tr":"ilan etmek / yaymak / yürürlüğe koymak","te":"Verb","tt":"Fiil","de":"To spread beliefs or ideas; or to announce a new law officially","dt":"İnanç veya fikirleri yaymak; veya yeni bir yasayı resmen ilan etmek","e1":"The new law was promulgated yesterday.","e1t":"Yeni yasa dün ilan edildi (yürürlüğe girdi).","e2":"To promulgate ideas of freedom.","e2t":"Özgürlük fikirlerini yaymak."},{"w":"propellant / propellent","tr":"itici güç / sevk yakıtı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance used to move something forward, like a rocket","dt":"Roket gibi bir şeyi ileri hareket ettirmek için kullanılan madde","e1":"Rocket propellant.","e1t":"Roket yakıtı.","e2":"The propellant in the spray can.","e2t":"Sprey kutusundaki itici gaz."},{"w":"propensity","tr":"eğilim / meyil / yatkınlık","te":"Noun","tt":"İsim","de":"A natural tendency to behave in a particular way","dt":"Belirli bir şekilde davranmaya yönelik doğal eğilim","e1":"A propensity for violence.","e1t":"Şiddete eğilim.","e2":"Her propensity to talk too much.","e2t":"Onun çok konuşma yatkınlığı."},{"w":"prophetic","tr":"kehanet dolu / geleceği gören","te":"Adjective","tt":"Sıfat","de":"Correctly stating what will happen in the future","dt":"Gelecekte ne olacağını doğru bir şekilde belirten","e1":"His warnings proved to be prophetic.","e1t":"Uyarılarının kehanet niteliğinde (doğru) olduğu kanıtlandı.","e2":"Prophetic dreams.","e2t":"Geleceği haber veren rüyalar."},{"w":"propinquity","tr":"yakınlık / akrabalık","te":"Noun","tt":"İsim","de":"Nearness in time or place, or a close relationship","dt":"Zaman, mekan veya ilişki bakımından yakınlık","e1":"The propinquity of the two events.","e1t":"İki olayın (zaman/mekan olarak) yakınlığı.","e2":"Close propinquity of blood.","e2t":"Kan yakınlığı (akrabalık)."},{"w":"propitiate","tr":"gönlünü almak / yatıştırmak","te":"Verb","tt":"Fiil","de":"To please someone and make them less angry (formal)","dt":"Birini memnun etmek ve öfkesini dindirmek (resmi)","e1":"To propitiate the gods with sacrifices.","e1t":"Kurbanlarla tanrıları yatıştırmak (gönlünü almak).","e2":"He made an effort to propitiate his boss.","e2t":"Patronunun gönlünü almaya çalıştı."},{"w":"propitious","tr":"elverişli / uğurlu / uygun","te":"Adjective","tt":"Sıfat","de":"Likely to result in success, or showing signs of success","dt":"Başarıyla sonuçlanması muhtemel olan veya başarı belirtileri gösteren","e1":"It was not a propitious time to start a business.","e1t":"İş kurmak için elverişli (uygun) bir zaman değildi.","e2":"Propitious conditions.","e2t":"Uygun koşullar."},{"w":"proponent","tr":"destekçi / savunucu","te":"Noun","tt":"İsim","de":"A person who speaks publicly in support of an idea","dt":"Bir fikri herkesin önünde destekleyen kişi","e1":"A leading proponent of nuclear energy.","e1t":"Nükleer enerjinin önde gelen savunucusu.","e2":"Proponents of the new law.","e2t":"Yeni yasanın destekçileri."},{"w":"propound","tr":"ileri sürmek / ortaya atmak","te":"Verb","tt":"Fiil","de":"To suggest a theory or belief for people to consider","dt":"İnsanların değerlendirmesi için bir teori veya inanç önermek","e1":"He propounded a new theory of evolution.","e1t":"Yeni bir evrim teorisi ortaya attı.","e2":"To propound a question.","e2t":"Bir soru ileri sürmek."},{"w":"propulsive","tr":"itici / sevk edici","te":"Adjective","tt":"Sıfat","de":"Pushing or driving something forward","dt":"Bir şeyi ileriye doğru iten veya süren","e1":"Propulsive force.","e1t":"İtici güç.","e2":"The propulsive power of the engine.","e2t":"Motorun itici gücü."},{"w":"prosaic","tr":"sıradan / alelade / sıkıcı / nesir gibi","te":"Adjective","tt":"Sıfat","de":"Ordinary and boring; or not like poetry","dt":"Sıradan ve sıkıcı; veya şiirsel olmayan","e1":"A prosaic lifestyle.","e1t":"Sıradan (alelade) bir yaşam tarzı.","e2":"The prosaic reality of everyday life.","e2t":"Günlük hayatın sıkıcı gerçekliği."},{"w":"proscenium","tr":"sahne önü / sahne kemeri","te":"Noun","tt":"İsim","de":"The part of a theater stage that is in front of the curtain","dt":"Bir tiyatro sahnesinin perdenin önünde kalan kısmı","e1":"To stand on the proscenium.","e1t":"Sahne önünde durmak.","e2":"Proscenium arch.","e2t":"Sahne kemeri."},{"w":"proscribe","tr":"yasaklamak / men etmek","te":"Verb","tt":"Fiil","de":"To forbid an action or practice officially","dt":"Bir eylemi veya uygulamayı resmi olarak yasaklamak","e1":"The government proscribed the political party.","e1t":"Hükümet siyasi partiyi yasakladı (men etti).","e2":"Proscribed organizations.","e2t":"Yasaklanmış örgütler."},{"w":"proselytize / proselytise","tr":"dinini değiştirtmek / kendi safına çekmek","te":"Verb","tt":"Fiil","de":"To try to persuade someone to change their religious or political beliefs","dt":"Birini dini veya siyasi inancını değiştirmesi için ikna etmeye çalışmak","e1":"They were accused of trying to proselytize the locals.","e1t":"Yerel halkın dinini değiştirmeye çalışmakla suçlandılar.","e2":"To proselytize for a cause.","e2t":"Bir dava için taraftar toplamak."},{"w":"prosody","tr":"şiir sanatı / vezin ve kafiye bilgisi / vurgu (dilbilim)","te":"Noun","tt":"İsim","de":"The study of rhythm and sound in poetry; or rhythm in speech","dt":"Şiirde ritim ve ses bilgisi; veya konuşmadaki ritim/vurgu","e1":"The prosody of English verse.","e1t":"İngiliz şiirinin vezin yapısı.","e2":"Emotional prosody.","e2t":"Duygusal vurgu (konuşmadaki)."},{"w":"prostrate","tr":"yere kapanmış / bitkin / dermanı kesilmiş","te":"Adjective/Verb","tt":"Lying with the face down; or too tired to move","de":"Yüzükoyun yere uzanmış; veya hareket edemeyecek kadar bitkin","dt":"He lay prostrate on the floor.","e1":"Yerde boylu boyunca (yüzükoyun) yatıyordu.","e1t":"Prostrate with grief.","e2":"Kederden yıkılmış (dermanı kesilmiş).","e2t":""},{"w":"protean","tr":"değişken / çok yönlü / kılıktan kılığa giren","te":"Adjective","tt":"Sıfat","de":"Able to change easily or take on different forms","dt":"Kolayca değişebilen veya farklı biçimlere bürünebilen","e1":"A protean actor.","e1t":"Kılıktan kılığa giren (çok yönlü) bir oyuncu.","e2":"The protean nature of the virus.","e2t":"Virüsün değişken doğası."},{"w":"protract","tr":"uzatmak / süresini uzatmak","te":"Verb","tt":"Fiil","de":"To make something last for a long time (formal)","dt":"Bir şeyin uzun sürmesini sağlamak (resmi)","e1":"A protracted legal battle.","e1t":"Uzun süren (uzatılmış) bir hukuk savaşı.","e2":"To protract a visit.","e2t":"Bir ziyareti uzatmak."},{"w":"protrude","tr":"dışarı çıkmak / fırlamak / çıkıntı yapmak","te":"Verb","tt":"Fiil","de":"To stick out from or through something","dt":"Bir şeyin içinden dışarı doğru çıkmak","e1":"His teeth protrude slightly.","e1t":"Dişleri hafifçe dışarı çıkık.","e2":"Rocks protruding from the sea.","e2t":"Denizden fırlamış (çıkıntı yapan) kayalar."},{"w":"protuberance","tr":"çıkıntı / şişlik / yumru","te":"Noun","tt":"Isim","de":"A part of something that sticks out from the surface","dt":"Bir şeyin yüzeyinden dışarı sarkan/çıkan parça","e1":"A bony protuberance on the back of the head.","e1t":"Başın arkasındaki kemikli bir çıkıntı.","e2":"Solar protuberances.","e2t":"Güneş çıkıntıları (patlamaları)."},{"w":"provenance","tr":"köken / kaynak / menşe","te":"Noun","tt":"İsim","de":"The place of origin of something (formal)","dt":"Bir şeyin kökeni veya çıktığı yer (resmi)","e1":"The provenance of the painting is unknown.","e1t":"Tablonun kökeni (nereden geldiği) bilinmiyor.","e2":"Of doubtful provenance.","e2t":"Kaynağı şüpheli."},{"w":"provender","tr":"erzak / yem / azık","te":"Noun","tt":"İsim","de":"Food, especially for animals (formal)","dt":"Özellikle hayvanlar için gıda, yem (resmi)","e1":"To store provender for the winter.","e1t":"Kış için yem (erzak) depolamak.","e2":"Human provender.","e2t":"İnsan azığı."},{"w":"provident","tr":"tedbirli / ileriyi düşen / tutumlu","te":"Adjective","tt":"Sıfat","de":"Making arrangements for future needs","dt":"Gelecekteki ihtiyaçlar için hazırlık yapan (ileriyi düşünen)","e1":"A provident father.","e1t":"Tedbirli (ailesinin geleceğini düşünen) bir baba.","e2":"To be provident with money.","e2t":"Para konusunda tutumlu (tedbirli) olmak."},{"w":"provincial","tr":"taşralı / dar görüşlü / yerel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to an area outside a capital; or narrow","dt":"minded","e1":"Başkent dışındaki yerlerle ilgili; veya dar görüşlü","e1t":"A provincial town.","e2":"Bir taşra kasabası.","e2t":"He has a very provincial outlook."},{"w":"provisional","tr":"geçici / eğreti","te":"Adjective","tt":"Sıfat","de":"For the present time but likely to change","dt":"Şu an için geçerli ama değişmesi muhtemel olan","e1":"A provisional government.","e1t":"Geçici hükümet.","e2":"Provisional arrangements.","e2t":"Geçici düzenlemeler."},{"w":"proviso","tr":"şart / hüküm / kayıt","te":"Noun","tt":"İsim","de":"A condition that must be accepted before an agreement is made","dt":"Bir anlaşma yapılmadan önce kabul edilmesi gereken şart","e1":"He agreed to the plan with the proviso that...","e1t":"... şartıyla planı kabul etti.","e2":"Under the provisos of the contract.","e2t":"Sözleşme hükümleri uyarınca."},{"w":"provocation","tr":"kışkırtma / tahrik","te":"Noun","tt":"İsim","de":"An action that is intended to make someone angry","dt":"Birini kızdırmayı amaçlayan eylem","e1":"He acted under extreme provocation.","e1t":"Büyük bir tahrik (kışkırtma) altında hareket etti.","e2":"An unprovoked attack.","e2t":"Durup dururken yapılan (tahrik edilmemiş) saldırı."},{"w":"prowess","tr":"kahramanlık / üstün yetenek / maharet","te":"Noun","tt":"İsim","de":"Great skill at doing something; or bravery","dt":"Bir şeyi yapmadaki büyük beceri; veya kahramanlık","e1":"Academic prowess.","e1t":"Akademik beceri (üstünlük).","e2":"Military prowess.","e2t":"Askeri kahramanlık/beceri."},{"w":"prude","tr":"aşırı ahlakçı / iffet kumkuması / namuslu geçinen","te":"Noun","tt":"Isim","de":"A person who is easily shocked by matters relating to sex","dt":"Cinsellikle ilgili konularda kolayca şoke olan (aşırı muhafazakar) kişi","e1":"Don't be such a prude!","e1t":"Bu kadar kuralcı (tutucu) olma!","e2":"Prudish (adjective).","e2t":"Aşırı ahlakçı."},{"w":"prudence","tr":"tedbir / sağduyu / ihtiyat","te":"Noun","tt":"İsim","de":"Behavior that is careful and avoids risks","dt":"Risklerden kaçınan, dikkatli davranış","e1":"Financial prudence.","e1t":"Finansal tedbir (ihtiyat).","e2":"To act with great prudence.","e2t":"Büyük bir sağduyuyla hareket etmek."},{"w":"prune","tr":"budamak / azaltmak / kuru erik","te":"Verb/Noun","tt":"Fiil/İsim","de":"To cut off branches; or to reduce something","dt":"Dallarını kesmek; veya bir şeyi (maliyeti vb.) azaltmak","e1":"To prune the roses.","e1t":"Gülleri budamak.","e2":"The company is pruning its workforce.","e2t":"Şirket işgücünü azaltıyor (buduyor)."},{"w":"prurient","tr":"şehvetli / müstehcen meraklısı","te":"Adjective","tt":"Sıfat","de":"Having too much interest in sexual matters","dt":"Cinsel konulara aşırı (ve nahoş) ilgi duyan","e1":"Prurient curiosity.","e1t":"Müstehcen konulara duyulan merak.","e2":"Prurient interests.","e2t":"Şehvetli ilgiler."},{"w":"pseudonym","tr":"takma ad / mahlas / takma isim","te":"Noun","tt":"İsim","de":"A false name used by a writer","dt":"Bir yazar tarafından kullanılan sahte ad","e1":"He wrote under the pseudonym \"Mark Twain\".","e1t":"\"Mark Twain\" takma adıyla yazdı.","e2":"To use a pseudonym.","e2t":"Mahlas kullanmak."},{"w":"psyche","tr":"ruh / tinsel yapı / zihin","te":"Noun","tt":"İsim","de":"The human soul, mind, or spirit","dt":"İnsan ruhu veya zihni","e1":"The feminine psyche.","e1t":"Kadın ruhu (psikolojisi).","e2":"Deep in the human psyche.","e2t":"İnsan ruhunun derinliklerinde."},{"w":"pterodactyl","tr":"uçan dinozor / pterodaktil","te":"Noun","tt":"İsim","de":"An extinct flying reptile with large wings","dt":"Büyük kanatları olan, soyu tükenmiş uçan sürüngen","e1":"","e1t":"","e2":"","e2t":""},{"w":"puberty","tr":"ergenlik","te":"Noun","tt":"İsim","de":"The stage in life when a child's body becomes an adult's","dt":"Çocuğun vücudunun yetişkin vücuduna dönüştüğü yaşam evresi","e1":"To reach puberty.","e1t":"Ergenliğe girmek.","e2":"The changes associated with puberty.","e2t":"Ergenlikle ilgili değişimler."},{"w":"puerile","tr":"çocuksu / toy / saçma","te":"Adjective","tt":"Sıfat","de":"Silly and childish (formal)","dt":"Aptalca ve çocuksu (resmi)","e1":"A puerile joke.","e1t":"Çocuksu bir şaka.","e2":"Puerile behavior.","e2t":"Toyca (olgunlaşmamış) davranış."},{"w":"pugilist","tr":"boksör","te":"Noun","tt":"İsim","de":"A person who fights with their fists; a boxer (formal)","dt":"Yumruklarıyla dövüşen kişi; boksör (resmi)","e1":"A professional pugilist.","e1t":"Profesyonel boksör.","e2":"Pugilism (the sport of boxing).","e2t":"Boks sporu."},{"w":"pugnacity","tr":"kavgacılık / hırçınlık","te":"Noun","tt":"İsim","de":"A strong desire to argue or fight","dt":"Güçlü bir tartışma veya kavga etme arzusu","e1":"He was known for his pugnacity.","e1t":"Kavgacılığıyla bilinirdi.","e2":"Pugnacious (adjective).","e2t":"Kavgacı/hırçın."},{"w":"puissant","tr":"güçlü / kuvvetli / nüfuzlu","te":"Adjective","tt":"Sıfat","de":"Very powerful (literary)","dt":"Çok güçlü (edebi)","e1":"A puissant monarch.","e1t":"Güçlü bir hükümdar.","e2":"Puissant influence.","e2t":"Büyük nüfuz."},{"w":"pulchritude","tr":"güzellik / hüsün","te":"Noun","tt":"İsim","de":"Physical beauty (formal)","dt":"Fiziksel güzellik (resmi)","e1":"A woman of great pulchritude.","e1t":"Çok güzel (hüsün sahibi) bir kadın.","e2":"Pulchritudinous (adjective).","e2t":"Çok güzel."},{"w":"pulmonary","tr":"akciğerle ilgili / pulmoner","te":"Adjective","tt":"Sıfat","de":"Relating to the lungs","dt":"Akciğerlerle ilgili","e1":"Pulmonary disease.","e1t":"Akciğer hastalığı.","e2":"Pulmonary artery.","e2t":"Akciğer atardamarı."},{"w":"pulsate","tr":"zonklamak / çarpmak / titreşmek","te":"Verb","tt":"Fiil","de":"To beat or move with a regular rhythm","dt":"Düzenli bir ritimle çarpmak veya hareket etmek","e1":"The light pulsated in the darkness.","e1t":"Işık karanlıkta titreşiyordu.","e2":"A pulsating headache.","e2t":"Zonklayan bir baş ağrısı."},{"w":"pulverize / pulverise","tr":"toz haline getirmek / un ufak etmek / bozguna uğratmak","te":"Verb","tt":"Fiil","de":"To crush something into a fine powder; or to defeat completely","dt":"Bir şeyi toz haline getirmek; veya tamamen yenmek","e1":"The rocks were pulverized into dust.","e1t":"Kayalar toz haline getirildi.","e2":"Our team pulverized the opposition.","e2t":"Takımımız rakibi bozguna uğrattı."},{"w":"pummel / pommel","tr":"yumruklamak / dövmek / hırpalamak","te":"Verb","tt":"Fiil","de":"To hit someone or something repeatedly with your fists","dt":"Birini veya bir şeyi yumruklarla üst üste dövmek","e1":"He was pummelling the door with his fists.","e1t":"Kapıyı yumrukluyordu.","e2":"The boxer was pummelled by his opponent.","e2t":"Boksör rakibi tarafından evire çevire dövüldü."},{"w":"punctilious","tr":"çok titiz / kuralcı / özenli","te":"Adjective","tt":"Sıfat","de":"Very careful of good behavior and small details","dt":"Davranış ve küçük detaylar konusunda çok dikkatli/özenli","e1":"He was punctilious in his attention to detail.","e1t":"Detaylara gösterdiği dikkat konusunda çok titizdi.","e2":"Punctilious politeness.","e2t":"Aşırı (titiz) nezaket."},{"w":"pundit","tr":"uzman / bilirkişi / yorumcu","te":"Noun","tt":"İsim","de":"A person who knows a lot about a subject and gives opinions","dt":"Bir konuyu çok iyi bilen ve fikir beyan eden kişi","e1":"Political pundits.","e1t":"Siyasi yorumcular.","e2":"A football pundit.","e2t":"Futbol bilirkişisi."},{"w":"pungent","tr":"keskin kokulu / acı (tat) / iğneleyici","te":"Adjective","tt":"Sıfat","de":"Having a strong, sharp smell or taste; or (of remarks) direct and sharp","dt":"Keskin, sert bir koku/tada sahip olan; veya (söz için) iğneleyici","e1":"The pungent smell of onions.","e1t":"Soğanın keskin kokusu.","e2":"Pungent criticism.","e2t":"İğneleyici (sert) eleştiri."},{"w":"punitive","tr":"cezalandırıcı / cezai","te":"Adjective","tt":"Sıfat","de":"Intended as a punishment","dt":"Ceza amaçlı olan","e1":"Punitive measures.","e1t":"Cezalandırıcı önlemler.","e2":"Punitive taxes.","e2t":"(Cezalandırıcı düzeyde) yüksek vergiler."},{"w":"puny","tr":"cılız / çelimsiz / ehemmiyetsiz","te":"Adjective","tt":"Sıfat","de":"Small and weak; or not effective","dt":"Küçük ve zayıf; veya etkisiz","e1":"A puny little man.","e1t":"Cılız, küçük bir adam.","e2":"A puny attempt to solve the problem.","e2t":"Sorunu çözmek için gösterilen cılız (etkisiz) bir çaba."},{"w":"purport","tr":"iddia etmek /","te":"miş gibi görünmek / anlam","tt":"Verb/Noun","de":"Fiil/İsim","dt":"To claim to be or do something, even if false; or the meaning","e1":"Gerçek olmasa bile bir şeyi iddia etmek; veya (yazının vb.) anlamı","e1t":"The book purports to be a true story.","e2":"Kitap gerçek bir hikaye olduğunu iddia ediyor.","e2t":"I didn't understand the purport of his speech."},{"w":"purported","tr":"sözde / iddia edilen","te":"Adjective","tt":"Sıfat","de":"Claimed to be true, but not proved","dt":"Doğru olduğu iddia edilen ancak kanıtlanmamış","e1":"The purported victim of the crime.","e1t":"Suçun sözde kurbanı.","e2":"Purported experts.","e2t":"Sözde uzmanlar."},{"w":"purveyor","tr":"tedarikçi / satıcı","te":"Noun","tt":"İsim","de":"A person or business that sells or provides something","dt":"Bir şeyi satan veya sağlayan kişi/kuruluş","e1":"Purveyors of fine wines.","e1t":"Kaliteli şarap tedarikçileri.","e2":"A purveyor of gossip.","e2t":"Dedikodu yayan (tedarik eden) kişi."},{"w":"pusillanimous","tr":"korkak / ödlek / tabansız","te":"Adjective","tt":"Sıfat","de":"Very frightened of taking risks (formal)","dt":"Risk almaktan çok korkan, korkak (resmi)","e1":"A pusillanimous politician.","e1t":"Ödlek bir siyasetçi.","e2":"The authorities were too pusillanimous to act.","e2t":"Yetkililer harekete geçemeyecek kadar korkaktı."},{"w":"putative","tr":"varsayılan / sözde / kabul edilen","te":"Adjective","tt":"Sıfat","de":"Generally thought to be or to exist","dt":"Genel olarak öyle olduğu düşünülen veya kabul edilen","e1":"The putative father of the child.","e1t":"Çocuğun varsayılan (olduğu sanılan) babası.","e2":"The putative effects of the drug.","e2t":"İlacın varsayılan etkileri."},{"w":"putrefy","tr":"çürümek / kokuşmak","te":"Verb","tt":"Fiil","de":"To decay and produce a strong unpleasant smell","dt":"Çürümek ve nahoş bir koku yaymak","e1":"The meat had begun to putrefy.","e1t":"Et kokuşmaya (çürümeye) başlamıştı.","e2":"Putrefying organic waste.","e2t":"Çürüyen organik atık."},{"w":"putrid","tr":"kokuşmuş / iğrenç / bozulmuş","te":"Adjective","tt":"Sıfat","de":"Decayed and having an unpleasant smell","dt":"Çürümüş ve nahoş bir kokusu olan","e1":"The putrid smell of rotting fish.","e1t":"Çürüyen balığın kokuşmuş kokusu.","e2":"Putrid air.","e2t":"Bozulmuş (pis) hava."},{"w":"pyromaniac","tr":"kundakçı / piroman","te":"Noun","tt":"İsim","de":"A person who has an uncontrollable desire to set fire to things","dt":"Eşyaları ateşe vermek için kontrol edilemez bir istek duyan kişi","e1":"The fire was started by a pyromaniac.","e1t":"Yangın bir kundakçı (piroman) tarafından çıkarıldı.","e2":"","e2t":""},{"w":"quadruped","tr":"dört ayaklı","te":"Noun","tt":"İsim","de":"An animal that has four feet","dt":"Dört ayağı olan hayvan","e1":"Horses and dogs are quadrupeds.","e1t":"Atlar ve köpekler dört ayaklıdırlar.","e2":"A large quadruped.","e2t":"Büyük bir dört ayaklı."},{"w":"quaff","tr":"dikmek / büyük yudumlarla içmek","te":"Verb","tt":"Fiil","de":"To drink something quickly or in large amounts (formal)","dt":"Bir şeyi hızlıca veya büyük miktarlarda içmek (resmi)","e1":"They quaffed large amounts of beer.","e1t":"Büyük miktarlarda birayı mideye indirdiler (diklediler).","e2":"","e2t":""},{"w":"quagmire","tr":"bataklık / zor durum / çıkmaz","te":"Noun","tt":"İsim","de":"An area of soft wet ground; or a difficult situation","dt":"Yumuşak, ıslak toprak alanı; veya zor bir durum","e1":"To be stuck in a legal quagmire.","e1t":"Hukuki bir çıkmaza (bataklığa) saplanmak.","e2":"The heavy rain turned the field into a quagmire.","e2t":"Şiddetli yağmur tarlayı bataklığa çevirdi."},{"w":"quail","tr":"korkmak / ürkmek / bıldırcın","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel or show great fear; or a small bird","dt":"Büyük bir korku hissetmek veya göstermek; veya bıldırcın","e1":"He quailed at the thought of seeing her again.","e1t":"Onu tekrar görme düşüncesiyle ürktü.","e2":"Quail eggs.","e2t":"Bıldırcın yumurtası."},{"w":"qualms","tr":"vicdan azabı / kuşku / mide bulantısı","te":"Noun","tt":"İsim","de":"An uncomfortable feeling of doubt about whether you are doing the right thing","dt":"Doğru şeyi yapıp yapmadığına dair rahatsız edici şüphe duygusu","e1":"He had no qualms about lying to the police.","e1t":"Polise yalan söyleme konusunda hiçbir vicdan azabı (tereddüt) duymadı.","e2":"To have serious qualms.","e2t":"Ciddi kuşkuları olmak."},{"w":"quarry","tr":"taş ocağı / av / kurban","te":"Noun/Verb","tt":"İsim/Fiil","de":"A place where stone is dug out; or an animal being hunted","dt":"Taşın çıkarıldığı yer; veya avlanan hayvan/kişi","e1":"A granite quarry.","e1t":"Granit taş ocağı.","e2":"The hunters lost their quarry in the woods.","e2t":"Avcılar avlarını ormanda kaybettiler."},{"w":"quash","tr":"bastırmak / iptal etmek / hükümsüz kılmak","te":"Verb","tt":"Fiil","de":"To stop something by force; or to state officially that a legal decision is not valid","dt":"Güç kullanarak bir şeyi durdurmak; veya bir kararı resmen iptal etmek","e1":"To quash a rebellion.","e1t":"Bir isyanı bastırmak.","e2":"The conviction was quashed on appeal.","e2t":"Mahkumiyet kararı temyizde bozuldu (iptal edildi)."},{"w":"quay","tr":"rıhtım / iskele","te":"Noun","tt":"İsim","de":"A long structure where boats can be tied to load/unload","dt":"Teknelerin yükleme boşaltma için bağlandığı uzun yapı","e1":"A busy quay.","e1t":"Hareketli bir rıhtım.","e2":"To walk along the quay.","e2t":"Rıhtım boyunca yürümek."},{"w":"queasy","tr":"midesi bulanan / huzursuz","te":"Adjective","tt":"Sıfat","de":"Feeling that you are going to vomit; or nervous","dt":"Midesi bulanan; veya huzursuz/gergin","e1":"The sight of blood makes me queasy.","e1t":"Kan görmek midemi bulandırıyor.","e2":"I'm feeling a bit queasy about the exam.","e2t":"Sınav konusunda kendimi biraz huzursuz hissediyorum."},{"w":"quell","tr":"yatıştırmak / dindirmek / bastırmak","te":"Verb","tt":"Fiil","de":"To stop something such as a rebellion or a bad feeling","dt":"İsyan veya kötü bir duygu gibi bir şeyi durdurmak/yatıştırmak","e1":"To quell a riot.","e1t":"Bir ayaklanmayı bastırmak.","e2":"To quell someone's fears.","e2t":"Birinin korkularını dindirmek."},{"w":"querulous","tr":"mızmız / şikayetçi","te":"Adjective","tt":"Sıfat","de":"Often complaining, especially in a weak high voice","dt":"Genellikle (tiz bir sesle) sürekli şikayet eden","e1":"A querulous old man.","e1t":"Mızmız yaşlı bir adam.","e2":"In a querulous tone of voice.","e2t":"Şikayetçi bir ses tonuyla."},{"w":"quiescent","tr":"durgun / sessiz / hareketsiz","te":"Adjective","tt":"Sıfat","de":"At rest or not active","dt":"Dinlenme halinde veya aktif olmayan","e1":"The political situation is now quiescent.","e1t":"Siyasi durum şu an durgun.","e2":"A quiescent volcano.","e2t":"Sönmüş (hareketsiz) yanardağ."},{"w":"quietude","tr":"sessizlik / sükunet / huzur","te":"Noun","tt":"İsim","de":"A state of being silent and peaceful (formal)","dt":"Sessiz ve huzurlu olma durumu (resmi)","e1":"The quietude of the countryside.","e1t":"Kırsalın sükuneti.","e2":"In the quietude of the library.","e2t":"Kütüphanenin sessizliğinde."},{"w":"quintessence","tr":"öz / cevher / en saf örnek","te":"Noun","tt":"İsim","de":"The most typical or perfect example of something","dt":"Bir şeyin en tipik veya mükemmel örneği","e1":"He was the quintessence of an English gentleman.","e1t":"O, İngiliz beyefendisinin tam bir örneğiydi (özüydü).","e2":"The quintessence of the problem.","e2t":"Sorunun özü."},{"w":"quip","tr":"espri / nükte / iğneleyici söz","te":"Noun/Verb","tt":"İsim/Fiil","de":"A quick, clever, and often funny remark","dt":"Çabuk, zekice ve genellikle komik söz","e1":"He made a quip about his age.","e1t":"Yaşıyla ilgili bir espri yaptı.","e2":"To quip that...","e2t":"... diye nükte yapmak."},{"w":"quirk","tr":"gariplik / takıntı / tesadüf","te":"Noun","tt":"İsim","de":"An unusual habit or part of someone's character; or a strange accident","dt":"Birinin karakterindeki sıra dışı alışkanlık; veya garip tesadüf","e1":"We all have our little quirks.","e1t":"Hepimizin küçük gariplikleri (takıntıları) vardır.","e2":"By a quirk of fate.","e2t":"Kaderin bir cilvesi (garip bir tesadüf) sonucu."},{"w":"quisling","tr":"vatan haini / işbirlikçi","te":"Noun","tt":"İsim","de":"A person who helps an enemy that has taken control of their country","dt":"Ülkesini ele geçiren düşmana yardım eden kişi","e1":"He was branded a quisling.","e1t":"Vatan haini olarak damgalandı.","e2":"","e2t":""},{"w":"quixotic","tr":"hayalperest / uygulanması imkansız / şövalyece","te":"Adjective","tt":"Sıfat","de":"Having ideas that are not practical and likely to fail","dt":"Pratik olmayan ve başarısız olması muhtemel fikirleri olan","e1":"A quixotic attempt to change the law.","e1t":"Yasayı değiştirmek için gösterilen hayalperest bir çaba.","e2":"A quixotic mission.","e2t":"İmkansız (Don Kişotvari) bir görev."},{"w":"quizzical","tr":"sorgulayan / alaycı / şüpheci","te":"Adjective","tt":"Sıfat","de":"Seeming to ask a question without using words","dt":"Kelimeler kullanmadan soru sorar gibi görünen (alaycı/şüpheli)","e1":"A quizzical look.","e1t":"Sorgulayan (şüpheci) bir bakış.","e2":"She gave him a quizzical smile.","e2t":"Ona alaycı bir gülümseme attı."},{"w":"quorum","tr":"yeter sayı / nisap","te":"Noun","tt":"İsim","de":"The smallest number of people needed to be at a meeting for decisions to be made","dt":"Karar alınabilmesi için bir toplantıda bulunması gereken en az kişi sayısı","e1":"To have a quorum.","e1t":"Yeter sayıya sahip olmak.","e2":"There were not enough members present to form a quorum.","e2t":"Karar yeter sayısını (nisabı) oluşturacak kadar üye yoktu."},{"w":"rabid","tr":"kuduz / fanatik / gözü dönmüş","te":"Adjective","tt":"Sıfat","de":"Having rabies; or (of feelings) extreme and fanatical","dt":"Kuduz olan; veya (duygular için) aşırı ve fanatik","e1":"A rabid dog.","e1t":"Kuduz köpek.","e2":"A rabid supporter of the party.","e2t":"Partinin gözü dönmüş (fanatik) bir destekçisi."},{"w":"raconteur","tr":"hikaye anlatıcı / hoşsohbet kişi","te":"Noun","tt":"İsim","de":"A person who tells stories in a clever and funny way","dt":"Hikayeleri zekice ve komik bir şekilde anlatan kişi","e1":"He was a brilliant raconteur.","e1t":"Harika bir hikaye anlatıcısıydı.","e2":"A famous raconteur.","e2t":"Ünlü bir hoşsohbet kişi."},{"w":"raiment","tr":"giysi / kılık kıyafet","te":"Noun","tt":"İsim","de":"Clothes (literary)","dt":"Giysiler (edebi)","e1":"Ladies in fine raiment.","e1t":"Şık giysiler içindeki hanımlar.","e2":"To provide food and raiment.","e2t":"Aş ve iş (gıda ve giysi) sağlamak."},{"w":"ramification","tr":"sonuç / dallanma / karmaşık etki","te":"Noun","tt":"İsim","de":"The possible results of an action","dt":"Bir eylemin olası sonuçları (yansımaları)","e1":"The political ramifications of the decision.","e1t":"Kararın siyasi sonuçları.","e2":"To consider all the ramifications.","e2t":"Tüm ihtimalleri (yansımaları) değerlendirmek."},{"w":"ramify","tr":"dallanmanmak / kollara ayrılmak","te":"Verb","tt":"Fiil","de":"To spread and develop many parts or branches (formal)","dt":"Birçok parça veya kola ayrılarak yayılmak ve gelişmek (resmi)","e1":"A problem that ramifies into every part of life.","e1t":"Hayatın her alanına dallanan (yayılan) bir sorun.","e2":"Ramifying branches.","e2t":"Dallanan kollar."},{"w":"rampart","tr":"sur / koruma duvarı / tahkimat","te":"Noun","tt":"İsim","de":"A large wall of earth or stone built to protect a city","dt":"Bir şehri korumak için inşa edilen toprak veya taştan büyük duvar","e1":"To stand on the ramparts.","e1t":"Surların üzerinde durmak.","e2":"A rampart against the sea.","e2t":"Denize karşı bir koruma duvarı."},{"w":"ramshackle","tr":"derme çatma / yıkılacak gibi","te":"Adjective","tt":"Sıfat","de":"Badly made and likely to break or fall down","dt":"Kötü yapılmış ve kırılacak veya yıkılacak gibi görünen","e1":"A ramshackle old house.","e1t":"Derme çatma eski bir ev.","e2":"A ramshackle organization.","e2t":"Düzensiz (bozuk) bir organizasyon."},{"w":"rancor / rancour","tr":"kin / hınç / garez","te":"Noun","tt":"İsim","de":"A strong feeling of hate and tiredness (formal)","dt":"Güçlü bir nefret ve hınç duygusu (resmi)","e1":"They parted without rancor.","e1t":"Kin gütmeden ayrıldılar.","e2":"Full of rancor.","e2t":"Hınç dolu."},{"w":"rankle","tr":"içine dert olmak / acı vermek / sinir etmek","te":"Verb","tt":"Fiil","de":"To make someone feel angry or upset for a long time","dt":"Birinin uzun süre kızgın veya üzgün hissetmesine neden olmak","e1":"The insult still rankled in his mind.","e1t":"Hakaret hala zihnini kurcalıyordu (içine dert olmuştu).","e2":"His success rankled with his rivals.","e2t":"Başarısı rakiplerine acı verdi (onları sinir etti)."},{"w":"rant","tr":"bağırıp çağırmak / nutuk çekmek / ağzına geleni söylemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak or shout in a loud, uncontrolled, or angry way","dt":"Yüksek sesle, kontrolsüz veya öfkeli bir şekilde konuşmak","e1":"He ranted about the government for hours.","e1t":"Saatlerce hükümet hakkında bağırıp çağırdı.","e2":"A long rant.","e2t":"Uzun bir söylenme (nutuk)."},{"w":"rapacious","tr":"açgözlü / doymak bilmez / yağmacı","te":"Adjective","tt":"Sıfat","de":"Having or showing a strong wish to take things for yourself","dt":"Bir şeyleri kendisi için alma konusunda güçlü bir istek gösteren","e1":"Rapacious landlords.","e1t":"Açgözlü ev sahipleri.","e2":"A rapacious appetite for profit.","e2t":"Doymak bilmez bir kâr hırsı."},{"w":"rapport","tr":"uyum / iyi ilişki / mutabakat","te":"Noun","tt":"İsim","de":"A good understanding and agreement between people","dt":"İnsanlar arasındaki iyi anlayış ve anlaşma","e1":"To build a rapport with students.","e1t":"Öğrencilerle iyi bir diyalog (uyum) kurmak.","e2":"They have an excellent rapport.","e2t":"Aralarında harika bir uyum var."},{"w":"rapt","tr":"dalmış / mest olmuş / pürdikkat","te":"Adjective","tt":"Sıfat","de":"Giving complete attention to something","dt":"Bir şeye tüm dikkatini vermiş (mest olmuş)","e1":"She listened with rapt attention.","e1t":"Pürdikkat (mest olmuş halde) dinledi.","e2":"He looked at her with a rapt expression.","e2t":"Ona hayranlıkla karışık bir dikkatle baktı."},{"w":"rarefied / rarified","tr":"seçkin / seyrelmiş (hava) / az kişinin anladığı","te":"Adjective","tt":"Sıfat","de":"(Of air) with little oxygen; or intended for a small group","dt":"(Hava için) az oksijenli; veya küçük, seçkin bir grup için","e1":"The rarefied atmosphere of the mountain.","e1t":"Dağın seyrelmiş havası.","e2":"The rarefied world of academic philosophy.","e2t":"Akademik felsefenin (sadece uzmanların anladığı) seçkin dünyası."},{"w":"raspy","tr":"cızırtılı / tırmalayıcı / kısık (ses)","te":"Adjective","tt":"Sıfat","de":"(Of a voice) low and rough","dt":"(Ses için) alçak ve pürüzlü (tırmalayıcı)","e1":"A raspy voice.","e1t":"Cızırtılı bir ses.","e2":"He spoke in a raspy whisper.","e2t":"Cızırtılı bir fısıltıyla konuştu."},{"w":"ratiocination","tr":"akıl yürütme / muhakeme","te":"Noun","tt":"Isim","de":"The process of logical reasoning (formal)","dt":"Mantıklı akıl yürütme süreci (resmi)","e1":"A masterpiece of ratiocination.","e1t":"Bir akıl yürütme şaheseri.","e2":"Ratiocinative powers.","e2t":"Muhakeme güçleri."},{"w":"rationale","tr":"gerekçe / temel mantık / açıklama","te":"Noun","tt":"İsim","de":"The set of reasons or logical basis for a course of action","dt":"Bir eylem tarzının nedenleri veya mantıksal temeli","e1":"What is the rationale behind this decision?","e1t":"Bu kararın arkasındaki temel mantık (gerekçe) nedir?","e2":"To explain the rationale.","e2t":"Gerekçeyi açıklamak."},{"w":"rationalize / rationalise","tr":"rasyonelleştirmek / mantığa büründürmek / verimlileştirmek","te":"Verb","tt":"Fiil","de":"To try to find a logical reason for something, often to justify it","dt":"Bir şeyi haklı çıkarmak için mantıklı bir neden bulmaya çalışmak","e1":"To rationalize one's mistakes.","e1t":"Hatalarını mantığa büründürmek.","e2":"The company is trying to rationalize its production.","e2t":"Şirket üretimini verimlileştirmeye (mantıklı hale getirmeye) çalışıyor."},{"w":"raucous","tr":"gürültülü / kulak tırmalayıcı / hırçın","te":"Adjective","tt":"Sıfat","de":"Loud and unpleasant","dt":"Yüksek sesli ve nahoş","e1":"Raucous laughter.","e1t":"Kahkahalarla dolu gürültü.","e2":"A raucous party.","e2t":"Gürültülü ve taşkın bir parti."},{"w":"rave","tr":"saçmalamak / övmek / çılgın parti","te":"Verb/Noun","tt":"Fiil/İsim","de":"To speak with great enthusiasm; or to speak wildly","dt":"Büyük bir hevesle övmek; veya (sayıklayarak) saçmalamak","e1":"The critics raved about his new film.","e1t":"Eleştirmenler yeni filmini öve öve bitiremediler.","e2":"To rave in a fever.","e2t":"Ateşler içinde sayıklamak (saçmalamak)."},{"w":"ravel","tr":"dolaştırmak / karmakarışık etmek / sökmek","te":"Verb","tt":"Fiil","de":"To become more complicated or confused; or to untwist","dt":"Daha karmaşık/karışık hale gelmek; veya bir şeyi sökmek/çözmek","e1":"The situation continued to ravel.","e1t":"Durum daha da karmaşıklaşmaya devam etti.","e2":"To ravel out a knot.","e2t":"Bir düğümü çözmek. (Not: 'Unravel' kelimesi daha sık kullanılır)."},{"w":"ravenous","tr":"çok aç / kurt gibi acıkmış","te":"Adjective","tt":"Sıfat","de":"Extremely hungry","dt":"Son derece aç","e1":"I'm absolutely ravenous!","e1t":"Kurt gibi acıktım!","e2":"A ravenous appetite.","e2t":"Doymak bilmez bir iştah."},{"w":"raze","tr":"yerle bir etmek / yıkmak","te":"Verb","tt":"Fiil","de":"To completely destroy a city, building, etc.","dt":"Bir şehri veya binayı tamamen yıkmak","e1":"The village was razed to the ground.","e1t":"Köy yerle bir edildi.","e2":"To raze a forest.","e2t":"Bir ormanı dümdüz etmek."},{"w":"reactionary","tr":"gerici / tutucu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Opposing political or social change","dt":"Siyasi veya sosyal değişime karşı çıkan","e1":"Reactionary views.","e1t":"Gerici görüşler.","e2":"A reactionary government.","e2t":"Tutucu (değişim karşıtı) hükümet."},{"w":"reaper","tr":"biçerdöver / orakçı","te":"Noun","tt":"İsim","de":"A person or machine that cuts and collects crops","dt":"Ürünleri kesen ve toplayan kişi veya makine","e1":"The Grim Reaper (Death).","e1t":"Azrail (Ölüm meleği).","e2":"A mechanical reaper.","e2t":"Mekanik biçerdöver."},{"w":"rebuff","tr":"reddetmek / geri çevirmek / terslemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To refuse a suggestion or offer in an unfriendly way","dt":"Bir öneriyi veya teklifi kaba bir şekilde reddetmek","e1":"She rebuffed all his attempts to help her.","e1t":"Ona yardım etme çabalarının hepsini geri çevirdi.","e2":"To meet with a sharp rebuff.","e2t":"Sert bir reddedişle karşılaşmak."},{"w":"rebut","tr":"çürütmek / aksini ispatlamak","te":"Verb","tt":"Fiil","de":"To prove that a statement or an opinion is false","dt":"Bir ifadenin veya görüşün yanlış olduğunu kanıtlamak","e1":"To rebut an argument.","e1t":"Bir iddiayı çürütmek.","e2":"He was given a chance to rebut the allegations.","e2t":"İddiaları çürütmesi için ona bir şans verildi."},{"w":"recalcitrant","tr":"inatçı / dikbaşlı / söz dinlemez","te":"Adjective","tt":"Sıfat","de":"Unwilling to obey orders or to be controlled","dt":"Emirlere uymaya veya kontrol edilmeye isteksiz","e1":"A recalcitrant child.","e1t":"Söz dinlemez bir çocuk.","e2":"Recalcitrant prisoners.","e2t":"İnatçı (boyun eğmeyen) mahkumlar."},{"w":"recant","tr":"sözünü geri almak / caymak / inancını reddetmek","te":"Verb","tt":"Fiil","de":"To announce publicly that you no longer believe something","dt":"Artık bir şeye inanmadığını resmen (halk önünde) bildirmek","e1":"He was forced to recant his political beliefs.","e1t":"Siyasi inançlarından vazgeçmeye (onları reddetmeye) zorlandı.","e2":"To recant a statement.","e2t":"Bir ifadeyi geri çekmek."},{"w":"recapitulate","tr":"özetlemek / ana hatlarıyla tekrarlamak","te":"Verb","tt":"Fiil","de":"To repeat the main points of an explanation or description","dt":"Bir açıklamanın veya tanımın ana noktalarını tekrarlamak","e1":"To recapitulate the main events of the year.","e1t":"Yılın ana olaylarını özetlemek.","e2":"Let me recapitulate.","e2t":"Özetlememe izin verin."},{"w":"recast","tr":"yeniden şekillendirmek / oyuncu kadrosunu değiştirmek","te":"Verb","tt":"Fiil","de":"To change the form of something; or to change the actors in a play","dt":"Bir şeyin biçimini değiştirmek; veya oyuncuları değiştirmek","e1":"He recast his political speech.","e1t":"Siyasi konuşmasını yeniden şekillendirdi.","e2":"The role of the spy was recast.","e2t":"Casus rolü için yeni bir oyuncu seçildi."},{"w":"receptive","tr":"açık / anlayışlı / alıcı","te":"Adjective","tt":"Sıfat","de":"Willing to listen to and accept new ideas and suggestions","dt":"Yeni fikir ve önerileri dinlemeye ve kabul etmeye istekli","e1":"A receptive audience.","e1t":"(Fikirlere) açık bir dinleyici kitlesi.","e2":"To be receptive to new ideas.","e2t":"Yeni fikirlere açık olmak."},{"w":"recession","tr":"durgunluk / gerileme / ekonomik kriz","te":"Noun","tt":"İsim","de":"A period of low economic activity","dt":"Ekonomik faaliyetlerin düşük olduğu dönem","e1":"The country is in a deep recession.","e1t":"Ülke derin bir ekonomik durgunluk içinde.","e2":"To survive the recession.","e2t":"Ekonomik krizden sağ çıkmak."},{"w":"recidivism","tr":"suça dönüş / mükerrerlik","te":"Noun","tt":"İsim","de":"The act of a person repeating an undesirable behavior or crime","dt":"Bir kişinin istenmeyen bir davranışı veya suçu tekrarlaması","e1":"High rates of recidivism.","e1t":"Yüksek suça dönüş oranları.","e2":"Recidivism among young offenders.","e2t":"Genç suçlular arasında suçu tekrarlama eğilimi."},{"w":"reciprocate","tr":"karşılık vermek / karşılıklı yapmak","te":"Verb","tt":"Fiil","de":"To share the same feelings as someone else, or to behave in the same way","dt":"Birisiyle aynı duyguları paylaşmak veya aynı şekilde davranmak","e1":"I wasn't sure if she reciprocated my feelings.","e1t":"Duygularıma karşılık verip vermediğinden emin değildi.","e2":"To reciprocate a favor.","e2t":"Bir iyiliğe karşılık vermek."},{"w":"reclusive","tr":"inzivaya çekilmiş / toplumdan uzak","te":"Adjective","tt":"Sıfat","de":"Living alone and avoiding going outside or talking to other people","dt":"Yalnız yaşayan ve dışarı çıkmaktan veya insanlarla konuşmaktan kaçınan","e1":"A reclusive billionaire.","e1t":"İnzivaya çekilmiş bir milyarder.","e2":"He became increasingly reclusive.","e2t":"Giderek daha fazla içine kapandı (toplumdan uzaklaştı)."},{"w":"recondite","tr":"anlaşılması zor / derin / gizli (bilgi)","te":"Adjective","tt":"Sıfat","de":"Not known about by many people and difficult to understand","dt":"Pek çok kişi tarafından bilinmeyen ve anlaşılması zor","e1":"Recondite subjects like ancient law.","e1t":"Kadim hukuk gibi derin (anlaşılması güç) konular.","e2":"Recondite information.","e2t":"Gizli (herkesin bilmediği) bilgi."},{"w":"reconnaissance","tr":"keşif / ön araştırma","te":"Noun","tt":"İsim","de":"The process of getting information about an area for military purposes","dt":"Askeri amaçlarla bir alan hakkında bilgi edinme süreci","e1":"A reconnaissance mission.","e1t":"Keşif görevi.","e2":"Aerial reconnaissance.","e2t":"Havadan keşif."},{"w":"recourse","tr":"başvuru / çare / müracaat","te":"Noun","tt":"İsim","de":"Using something or someone as a way of getting help in a difficult situation","dt":"Zor bir durumda yardım almak için birine veya bir şeye başvurma","e1":"To have recourse to the law.","e1t":"Yasaya başvurmak.","e2":"Your only recourse is to sue them.","e2t":"Tek çareniz onlara dava açmaktır."},{"w":"recrimination","tr":"karşılıklı suçlama","te":"Noun","tt":"İsim","de":"Arguments between people who are blaming each other","dt":"Birbirini suçlayan insanlar arasındaki tartışmalar","e1":"A period of bitter recrimination.","e1t":"Sert karşılıklı suçlamaların yaşandığı bir dönem.","e2":"The meeting ended in mutual recriminations.","e2t":"Toplantı karşılıklı suçlamalarla bitti."},{"w":"rectitude","tr":"dürüstlük / doğruluk / erdem","te":"Noun","tt":"İsim","de":"Honesty and correct moral behavior (formal)","dt":"Dürüstlük ve doğru ahlaki davranış (resmi)","e1":"A man of unimpeachable rectitude.","e1t":"Dürüstlüğü tartışılamaz bir adam.","e2":"Moral rectitude.","e2t":"Ahlaki doğruluk."},{"w":"recumbent","tr":"uzanmış / yatan","te":"Adjective","tt":"Sıfat","de":"Lying down (formal)","dt":"Uzanmış halde (resmi)","e1":"A recumbent figure.","e1t":"Uzanmış bir figür.","e2":"Recumbent bicycle.","e2t":"Yatay bisiklet."},{"w":"recuperate","tr":"iyileşmek / sağlığına kavuşmak / (zararı) telafi etmek","te":"Verb","tt":"Fiil","de":"To become well again after an illness; or to get back money lost","dt":"Hastalıktan sonra iyileşmek; veya kaybedilen parayı geri almak","e1":"He is recuperating from a knee operation.","e1t":"Diz ameliyatından sonra iyileşiyor.","e2":"To recuperate one's losses.","e2t":"Zararlarını telafi etmek."},{"w":"recurrent","tr":"tekrarlayan / periyodik","te":"Adjective","tt":"Sıfat","de":"Happening again many times","dt":"Birçok kez tekrar eden","e1":"Recurrent headaches.","e1t":"Tekrarlayan baş ağrıları.","e2":"A recurrent theme in his books.","e2t":"Kitaplarında sürekli tekrarlanan bir tema."},{"w":"redolent","tr":"kokulu / çağrıştıran / andıran","te":"Adjective","tt":"Sıfat","de":"Smelling of something; or making you think of something","dt":"Bir şey gibi kokan; veya bir şeyi hatırlatan (çağrıştıran)","e1":"The air was redolent of roses.","e1t":"Hava gül kokuyordu.","e2":"An atmosphere redolent of the 1920s.","e2t":"1920'leri çağrıştıran bir atmosfer."},{"w":"redoubtable","tr":"korku uyandıran / dişli / saygın (rakip)","te":"Adjective","tt":"Sıfat","de":"Very strong and deserving of respect (formal)","dt":"Çok güçlü ve saygı duyulması gereken (resmi)","e1":"A redoubtable opponent.","e1t":"Dişli (korkulan) bir rakip.","e2":"Her redoubtable mother","e2t":"in"},{"w":"redress","tr":"düzeltmek / telafi etmek / tazmin etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put right a wrong or give payment for it","dt":"Bir yanlışı düzeltmek veya onun için ödeme yapmak","e1":"To redress the balance.","e1t":"Dengeyi yeniden sağlamak (düzeltmek).","e2":"To seek redress for grievances.","e2t":"Mağduriyetlerin giderilmesini (tazminini) istemek."},{"w":"reek","tr":"kötü kokmak / belli etmek (olumsuz)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To smell strongly and unpleasantly","dt":"Güçlü ve nahoş bir şekilde kokmak","e1":"The room reeked of tobacco.","e1t":"Oda tütün kokuyordu.","e2":"The whole deal reeks of corruption.","e2t":"Tüm anlaşma yolsuzluk kokuyor (yolsuzluk olduğu belli)."},{"w":"refaction / refraction","tr":"kırılma (ışık)","te":"Noun","tt":"İsim","de":"The change of direction of light or sound as it enters something","dt":"Işığın veya sesin bir ortama girerken yön değiştirmesi","e1":"Refraction of light in water.","e1t":"Işığın suda kırılması.","e2":"Atmospheric refraction.","e2t":"Atmosferik kırılma."},{"w":"refectory","tr":"yemekhane (okul/manastır)","te":"Noun","tt":"İsim","de":"A large room in a school or monastery where meals are eaten","dt":"Okul veya manastırda yemek yenen büyük oda","e1":"Lunch is served in the refectory.","e1t":"Öğle yemeği yemekhanede verilir.","e2":"The university refectory.","e2t":"Üniversite yemekhanesi."},{"w":"referendum","tr":"halk oylaması / referandum","te":"Noun","tt":"İsim","de":"A vote in which all the people in a country decide a question","dt":"Bir ülkedeki tüm insanların bir soruya karar verdiği oylama","e1":"To hold a referendum on independence.","e1t":"Bağımsızlık üzerine referandum yapmak.","e2":"The result of the referendum.","e2t":"Referandumun sonucu."},{"w":"refractory","tr":"inatçı / söz dinlemez / ateşe dayanıklı","te":"Adjective","tt":"Sıfat","de":"Difficult to control; or (of materials) resistant to heat","dt":"Kontrol edilmesi zor; veya (malzeme için) ısıya dayanıklı","e1":"A refractory child.","e1t":"Söz dinlemez (inatçı) çocuk.","e2":"Refractory bricks.","e2t":"Ateş tuğlası (ısıya dayanıklı)."},{"w":"refurbish","tr":"yenilemek / tadilat yapmak / elden geçirmek","te":"Verb","tt":"Fiil","de":"To clean and decorate a room or building to make it look new","dt":"Bir odayı veya binayı yeni görünmesi için temizlemek ve dekore etmek","e1":"The developers refurbished the old warehouse.","e1t":"Müteahhitler eski depoyu yenilediler.","e2":"A refurbished laptop.","e2t":"Elden geçirilmiş (yenilenmiş) dizüstü bilgisayar."},{"w":"regale","tr":"ağırlamak / eğlendirmek / ikram etmek","te":"Verb","tt":"Fiil","de":"To entertain someone with stories or food","dt":"Birini hikayelerle veya yemekle eğlendirmek","e1":"He regaled us with tales of his travels.","e1t":"Seyahat hikayeleriyle bizi eğlendirdi.","e2":"To regale guests with a feast.","e2t":"Misafirlere ziyafet çekmek."},{"w":"regatta","tr":"tekne yarışı / yelken yarışı","te":"Noun","tt":"İsim","de":"A sports event consisting of a series of boat or sailing races","dt":"Bir dizi tekne veya yelken yarışından oluşan spor etkinliği","e1":"The annual regatta.","e1t":"Geleneksel tekne yarışı.","e2":"To take part in a regatta.","e2t":"Yelken yarışına katılmak."},{"w":"regeneration","tr":"yenilenme / canlanma / rejenerasyon","te":"Noun","tt":"İsim","de":"The process of growing again; or improving an area","dt":"Yeniden büyüme süreci; veya bir alanı geliştirme/canlandırma","e1":"The regeneration of inner cities.","e1t":"Şehir merkezlerinin canlandırılması (kentsel dönüşüm).","e2":"Tissue regeneration.","e2t":"Doku yenilenmesi."},{"w":"regicide","tr":"kral katili / kral cinayeti","te":"Noun","tt":"İsim","de":"The crime of killing a king; or a person who kills a king","dt":"Bir kralı öldürme suçu; veya kralı öldüren kişi","e1":"He was executed for regicide.","e1t":"Kralı öldürdüğü için idam edildi.","e2":"","e2t":""},{"w":"regimen","tr":"diyet / rejim / tedavi planı","te":"Noun","tt":"İsim","de":"A set of rules about food or exercise to improve health","dt":"Sağlığı iyileştirmek için yiyecek veya egzersiz kuralları bütünü","e1":"A strict exercise regimen.","e1t":"Sıkı bir egzersiz programı.","e2":"A therapeutic regimen.","e2t":"Tedavi planı (rejimi)."},{"w":"reimburse","tr":"geri ödeme yapmak / masrafları karşılamak","te":"Verb","tt":"Fiil","de":"To pay back money to someone who has spent it for you","dt":"Sizin için para harcayan birine parasını geri ödemek","e1":"The company will reimburse you for your travel expenses.","e1t":"Şirket seyahat masraflarınızı size geri ödeyecektir.","e2":"To be fully reimbursed.","e2t":"Tüm masrafları geri almak."},{"w":"reiterate","tr":"tekrarlamak / defalarca söylemek","te":"Verb","tt":"Fiil","de":"To say something again, once or several times, to emphasize it","dt":"Vurgulamak için bir şeyi tekrar veya defalarca söylemek","e1":"Let me reiterate that we are here to help.","e1t":"Yardım için burada olduğumuzu tekrar etmeme izin verin.","e2":"To reiterate a point.","e2t":"Bir noktayı yinelemek."},{"w":"rejuvenate","tr":"gençleştirmek / canlandırmak / tazelemek","te":"Verb","tt":"Fiil","de":"To make someone or something look or feel young or energetic again","dt":"Birini veya bir şeyi tekrar genç veya enerjik hissettirmek/göstermek","e1":"The holiday rejuvenated her.","e1t":"Tatil onu gençleştirdi (canlandırdı).","e2":"Plans to rejuvenate the economy.","e2t":"Ekonomiyi canlandırma planları."},{"w":"relegate","tr":"sürgün etmek / alt dereceye indirmek / havale etmek","te":"Verb","tt":"Fiil","de":"To put someone or something into a lower or less important position","dt":"Birini veya bir şeyi daha düşük veya önemsiz bir konuma getirmek","e1":"The team was relegated to the second division.","e1t":"Takım ikinci lige düşürüldü.","e2":"To relegate a task to an assistant.","e2t":"Bir işi asistana havale etmek (devretmek)."},{"w":"relent","tr":"yumuşamak / razı olmak / merhamet etmek","te":"Verb","tt":"Fiil","de":"To act in a less severe way; or to agree after refusing","dt":"Daha az sert davranmak; veya reddettikten sonra razı olmak","e1":"The government finally relented and lowered taxes.","e1t":"Hükümet sonunda yumuşadı ve vergileri düşürdü.","e2":"The rain showed no sign of relenting.","e2t":"Yağmurun dineceği (hafifleyeceği) yoktu."},{"w":"remediable","tr":"düzeltilebilir / çaresi olan","te":"Adjective","tt":"Sıfat","de":"Capable of being corrected or cured","dt":"Düzeltilmesi veya iyileştirilmesi mümkün olan","e1":"A remediable mistake.","e1t":"Düzeltilebilir bir hata.","e2":"The situation is easily remediable.","e2t":"Durum kolayca telafi edilebilir."},{"w":"remedial","tr":"iyileştirici / düzeltici / takviye (eğitim)","te":"Adjective","tt":"Sıfat","de":"Intended to correct something, or to help slow learners","dt":"Bir şeyi düzeltmeyi amaçlayan veya yavaş öğrenenlere yardım eden","e1":"Remedial action.","e1t":"Düzeltici eylem.","e2":"Remedial classes in English.","e2t":"İngilizce takviye (yetiştirme) dersleri."},{"w":"reminiscence","tr":"hatıra / anı / geçmişi yad etme","te":"Noun","tt":"İsim","de":"A memory of a past event; or the act of remembering","dt":"Geçmiş bir olayın hatırası; veya hatırlama eylemi","e1":"Reminiscences of my childhood.","e1t":"Çocukluk hatıralarım.","e2":"To indulge in reminiscence.","e2t":"Geçmişi yad etmeye dalmak."},{"w":"remiss","tr":"ihmalkar / kusurlu / gevşek","te":"Adjective","tt":"Sıfat","de":"Careless and not doing a duty properly","dt":"Dikkatsiz ve bir görevi düzgün yapmayan","e1":"It was remiss of me not to write sooner.","e1t":"Daha önce yazmamış olmam benim ihmalkarlığımdı.","e2":"To be remiss in one's duties.","e2t":"Görevlerinde kusurlu (ihmalkar) olmak."},{"w":"remission","tr":"affetme / azalma / (hastalık) iyileşme dönemi","te":"Noun","tt":"İsim","de":"A period when a serious illness improves; or a reduction in a prison sentence","dt":"Ciddi bir hastalığın hafiflediği dönem; veya hapis cezasında indirim","e1":"Her cancer is in remission.","e1t":"Kanseri gerileme (iyileşme) döneminde.","e2":"Remission of sins.","e2t":"Günahların affı."},{"w":"remonstrance","tr":"itiraz / protesto / sitem","te":"Noun","tt":"İsim","de":"A complaint or protest (formal)","dt":"Şikayet veya protesto (resmi)","e1":"Despite my remonstrances, he continued.","e1t":"İtirazlarıma rağmen devam etti.","e2":"To make a formal remonstrance.","e2t":"Resmi bir itirazda bulunmak."},{"w":"remunerative","tr":"kazançlı / kârlı / paralı","te":"Adjective","tt":"Sıfat","de":"Providing a lot of money; profitable (formal)","dt":"Çok para sağlayan; kârlı (resmi)","e1":"A remunerative job.","e1t":"Kazançlı (iyi maaşlı) bir iş.","e2":"Remunerative activities.","e2t":"Kârlı faaliyetler."},{"w":"rend","tr":"yırtmak / parçalamak / koparmak","te":"Verb","tt":"Fiil","de":"To tear something into two or more pieces (literary)","dt":"Bir şeyi iki veya daha fazla parçaya yırtmak (edebi)","e1":"Loud cries rent the air.","e1t":"Yüksek çığlıklar havayı yırttı (parçaladı).","e2":"A country rent by civil war.","e2t":"İç savaşla parçalanmış bir ülke."},{"w":"rendition","tr":"yorumlama / icra / teslim etme","te":"Noun","tt":"İsim","de":"A particular way of performing a song or piece of art; or a translation","dt":"Bir şarkı veya sanat eserinin özel bir şekilde icra edilmesi; veya çeviri","e1":"A moving rendition of the national anthem.","e1t":"Milli marşın duygusal bir icrası (yorumu).","e2":"Rendition of a poem.","e2t":"Bir şiirin çevirisi/yorumu."},{"w":"renegade","tr":"dönek / hain / asi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who leaves a group to join an enemy; or behaving in a way that is not expected","dt":"Düşmana katılmak için grubu terk eden kişi; veya beklenmedik (asi) davranan","e1":"A renegade soldier.","e1t":"Dönek bir asker.","e2":"Renegade states.","e2t":"Asi (haydut) devletler."},{"w":"renege","tr":"sözünden dönmek / caymak","te":"Verb","tt":"Fiil","de":"To fail to keep a promise or an agreement","dt":"Bir sözü veya anlaşmayı tutmamak","e1":"He reneged on his promise to help.","e1t":"Yardım etme sözünden döndü.","e2":"To renege on a deal.","e2t":"Bir anlaşmadan caymak."},{"w":"reparable","tr":"onarılabilir / düzeltilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be repaired","dt":"Onarılması mümkün olan","e1":"Reparable damage.","e1t":"Onarılabilir hasar.","e2":"The mistake is easily reparable.","e2t":"Hata kolayca düzeltilebilir. (Not: 'Irreparable' kelimesinin zıttıdır)."},{"w":"reparation","tr":"tazminat / onarım / telafi","te":"Noun","tt":"İsim","de":"Payment made for damage or a wrong; or the act of repairing","dt":"Verilen zarar veya yanlış için ödenen bedel; veya onarma eylemi","e1":"War reparations.","e1t":"Savaş tazminatları.","e2":"To make reparation for the damage.","e2t":"Zararı telafi etmek (tazmin etmek)."},{"w":"repartee","tr":"hazırcevaplık / nükte / zekice karşılık","te":"Noun","tt":"İsim","de":"Quick and clever remarks and replies","dt":"Çabuk, zekice cevaplar ve karşılıklar","e1":"He was famous for his witty repartee.","e1t":"Hazırcevaplığı ve nükteleriyle ünlüydü.","e2":"An entertaining repartee.","e2t":"Eğlenceli bir karşılıklı nükteleşme."},{"w":"repatriate","tr":"vatanına geri göndermek / ülkesine iade etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To send someone back to their own country","dt":"Birini kendi ülkesine geri göndermek","e1":"The government decided to repatriate the refugees.","e1t":"Hükümet mültecileri ülkelerine geri göndermeye karar verdi.","e2":"Repatriation of funds (finance).","e2t":"Fonların (paranın) ana ülkeye transferi."},{"w":"repercussion","tr":"yansıma / yankı / dolaylı sonuç","te":"Noun","tt":"İsim","de":"An effect or consequence of some action or event","dt":"Bir eylem veya olayın etkisi veya sonucu (yansıması)","e1":"Serious repercussions for the economy.","e1t":"Ekonomi üzerinde ciddi yansımalar (sonuçlar).","e2":"The news had global repercussions.","e2t":"Haber küresel yankı uyandırdı."},{"w":"repertoire","tr":"repertuvar / dağarcık","te":"Noun","tt":"İsim","de":"The list of songs, plays, or skills that someone can perform","dt":"Birinin sergileyebileceği şarkı, oyun veya becerilerin listesi","e1":"An extensive repertoire of jazz songs.","e1t":"Geniş bir caz şarkıları repertuvarı.","e2":"A wide repertoire of teaching techniques.","e2t":"Geniş bir öğretim teknikleri dağarcığı."},{"w":"replete","tr":"dolu / ağzına kadar dolu / doymuş","te":"Adjective","tt":"Sıfat","de":"Full, especially with food; or well","dt":"supplied with something","e1":"Özellikle yemekle dolu; veya bir şeyle iyi donatılmış","e1t":"A heart replete with hope.","e2":"Umut dolu bir kalp.","e2t":"The book is replete with photographs."},{"w":"replicate","tr":"kopyalamak / aynısını yapmak / tekrarlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To make or do something again in exactly the same way","dt":"Bir şeyi tam olarak aynı şekilde tekrar yapmak","e1":"To replicate an experiment.","e1t":"Bir deneyi tekrarlamak.","e2":"We hope to replicate this success elsewhere.","e2t":"Bu başarıyı başka yerlerde de tekrarlamayı (kopyalamayı) umuyoruz."},{"w":"repose","tr":"istirahat / huzur / (bir yerde) durmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A state of rest, sleep, or tranquility","dt":"Dinlenme, uyku veya sükunet hali","e1":"In a state of repose.","e1t":"İstirahat (huzur) halinde.","e2":"Her features were calm in repose.","e2t":"Dinlenirken (yüz hatları) sakindi."},{"w":"reprehensible","tr":"kınanacak / kusurlu / ayıp","te":"Adjective","tt":"Sıfat","de":"Deserving blame or strong criticism (formal)","dt":"Suçlanmayı veya güçlü eleştiriyi hak eden (resmi)","e1":"Reprehensible behavior.","e1t":"Kınanacak davranış.","e2":"A morally reprehensible act.","e2t":"Ahlaken kusurlu (ayıp) bir eylem."},{"w":"reprimand","tr":"azarlamak / kınamak / ihtar","te":"Verb/Noun","tt":"Fiil/İsim","de":"To tell someone officially that they have done something wrong","dt":"Birine resmi olarak yanlış yaptığını söylemek (azarlamak)","e1":"He was severely reprimanded for his conduct.","e1t":"Davranışından dolayı sertçe azarlandı (ihtar aldı).","e2":"A formal reprimand.","e2t":"Resmi kınama."},{"w":"reprisal","tr":"misilleme / kısasa kısas","te":"Noun","tt":"İsim","de":"An act of damage or injury against an enemy who has harmed you","dt":"Size zarar veren bir düşmana karşı yapılan misilleme","e1":"To carry out reprisals.","e1t":"Misilleme yapmak.","e2":"Fear of reprisals.","e2t":"Misilleme korkusu."},{"w":"reprobate","tr":"ahlaksız / sefih / haylaz","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person of bad character and no morals","dt":"Kötü karakterli ve ahlaksız kişi","e1":"A drunken old reprobate.","e1t":"Sarhoş, ahlaksız bir ihtiyar.","e2":"Reprobate behavior.","e2t":"Ahlaksızca davranış."},{"w":"reprove","tr":"azarlamak / kınamak / sitem etmek","te":"Verb","tt":"Fiil","de":"To tell someone that you disapprove of their behavior (formal)","dt":"Birine davranışını onaylamadığını söylemek (resmi)","e1":"The teacher reproved the boys for whispering.","e1t":"Öğretmen çocukları fısıldaştıkları için azarladı (uyardı).","e2":"To reprove someone gently.","e2t":"Birine nazikçe sitem etmek."},{"w":"repugnant","tr":"iğrenç / itici / zıt / nahoş","te":"Adjective","tt":"Sıfat","de":"Very unpleasant and causing a feeling of disgust","dt":"Çok nahoş ve tiksinti uyandıran","e1":"The idea was repugnant to him.","e1t":"Fikir ona iğrenç (itici) geldi.","e2":"Repugnant behavior.","e2t":"Tiksindirici davranış."},{"w":"repulse","tr":"püskürtmek / reddetmek / soğutmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To push away an enemy; or to refuse an offer rudely","dt":"Bir düşmanı püskürtmek; veya bir teklifi kabaca reddetmek","e1":"The attack was repulsed.","e1t":"Saldırı püskürtüldü.","e2":"Her advances were repulsed.","e2t":"Yakınlaşma çabaları reddedildi."},{"w":"reputable","tr":"saygın / itibarlı / adı sanı belli","te":"Adjective","tt":"Sıfat","de":"Having a good reputation and able to be trusted","dt":"İyi bir itibarı olan ve güvenilebilen","e1":"A reputable company.","e1t":"Saygın (güvenilir) bir şirket.","e2":"To buy from a reputable dealer.","e2t":"İtibarlı bir satıcıdan satın almak."},{"w":"reputed","tr":"söylenen / sanılan / sözde","te":"Adjective","tt":"Sıfat","de":"Believed by many people to be something","dt":"Birçok kişi tarafından öyle olduğu düşünülen","e1":"He is the reputed author of the book.","e1t":"Kitabın yazarı olduğu söyleniyor (sanılıyor).","e2":"Her reputed wealth.","e2t":"Onun sözde (olduğu sanılan) serveti."},{"w":"requiem","tr":"ağıt / ölünün ruhu için dua / rekviyem","te":"Noun","tt":"İsim","de":"A mass or a piece of music at a funeral","dt":"Cenazedeki tören veya müzik parçası","e1":"Mozart's Requiem.","e1t":"Mozart'ın Rekviyem'i.","e2":"To sing a requiem.","e2t":"Ağıt yakmak (ölüm duası etmek)."},{"w":"requite","tr":"karşılığını vermek / telafi etmek / ödeşmek","te":"Verb","tt":"Fiil","de":"To give something in return for a favor or a hurt (formal)","dt":"Bir iyiliğin veya zararın karşılığını vermek (resmi)","e1":"Unrequited love (one","e1t":"sided).","e2":"Karşılıksız aşk.","e2t":"To requite a kindness."},{"w":"rescind","tr":"iptal etmek / yürürlükten kaldırmak / feshetmek","te":"Verb","tt":"Fiil","de":"To state officially that a law or agreement is no longer valid","dt":"Bir yasanın veya anlaşmanın artık geçerli olmadığını resmen bildirmek","e1":"The policy was rescinded after public protests.","e1t":"Politika, halk protestolarından sonra iptal edildi (geri çekildi).","e2":"To rescind an offer.","e2t":"Bir teklifi geri çekmek."},{"w":"resentment","tr":"dargınlık / kırgınlık / içerleme","te":"Noun","tt":"İsim","de":"A feeling of anger because you have been forced to accept something","dt":"Kabul etmeye zorlandığınız bir şeyden dolayı duyulan öfke/kırgınlık","e1":"To feel deep resentment.","e1t":"Derin bir kırgınlık (içerleme) duymak.","e2":"His success caused a lot of resentment.","e2t":"Başarısı birçok kişide dargınlığa (hasetliğe) yol açtı."},{"w":"resolution","tr":"karar / azim / çözünürlük / çözüm","te":"Noun","tt":"İsim","de":"A formal decision; or the quality of being determined","dt":"Resmi bir karar; veya kararlılık/azim niteliği","e1":"New Year's resolutions.","e1t":"Yeni yıl kararları.","e2":"To show great resolution.","e2t":"Büyük bir azim sergilemek."},{"w":"resonant","tr":"yankılanan / çınlayan / derin ve gür","te":"Adjective","tt":"Sıfat","de":"(Of a sound) clear and deep; or making you think of something","dt":"(Ses için) net ve derin; veya bir şeyi çağrıştıran","e1":"A resonant voice.","e1t":"Gür (yankılanan) bir ses.","e2":"Words resonant with meaning.","e2t":"Anlam yüklü (derin) sözler."},{"w":"respite","tr":"ara / mola / mühlet / dinlenme","te":"Noun","tt":"İsim","de":"A short period of rest or relief from something difficult","dt":"Zor bir şeye verilen kısa bir ara veya dinlenme","e1":"To give someone a brief respite.","e1t":"Birine kısa bir nefes (ara) aldırmak.","e2":"Working without respite.","e2t":"Aralıksız (durup dinlenmeden) çalışmak."},{"w":"resplendent","tr":"görkemli / parlak / ışıl ışıl","te":"Adjective","tt":"Sıfat","de":"Having a very bright or beautiful appearance","dt":"Çok parlak veya güzel bir görünüşü olan","e1":"Resplendent in her wedding dress.","e1t":"Gelinliği içinde ışıl ışıl (görkemli).","e2":"The garden was resplendent with flowers.","e2t":"Bahçe çiçeklerle muhteşem görünüyordu."},{"w":"responsive","tr":"duyarlı / tepki veren / anlayışlı","te":"Adjective","tt":"Sıfat","de":"Reacting quickly and positively to something","dt":"Bir şeye hızlı ve olumlu tepki veren","e1":"A responsive audience.","e1t":"Duyarlı (tepki veren) bir dinleyici kitlesi.","e2":"Responsive design (web).","e2t":"Duyarlı (ekrana uyum sağlayan) tasarım."},{"w":"restive","tr":"huzursuz / sabırsız / ele avuca sığmaz","te":"Adjective","tt":"Sıfat","de":"Unwilling to be controlled or be patient","dt":"Kontrol edilmeye veya sabırlı olmaya isteksiz","e1":"The crowd was growing restive.","e1t":"Kalabalık huzursuzlaşmaya (sabırsızlanmaya) başlıyordu.","e2":"A restive horse.","e2t":"Huysuz (yerinde duramayan) bir at."},{"w":"restraint","tr":"kısıtlama / otokontrol / sükunet","te":"Noun","tt":"İsim","de":"Calm and controlled behavior; or something that limits freedom","dt":"Sakin ve kontrollü davranış; veya özgürlüğü sınırlayan şey","e1":"To show remarkable restraint.","e1t":"Olağanüstü bir otokontrol sergilemek.","e2":"Wage restraints.","e2t":"Maaş kısıtlamaları."},{"w":"resumption","tr":"yeniden başlama / devam etme","te":"Noun","tt":"İsim","de":"The act of starting something again after a pause","dt":"Bir ara verildikten sonra bir şeye tekrar başlama","e1":"The resumption of negotiations.","e1t":"Müzakerelerin yeniden başlaması.","e2":"Resumption of normal service.","e2t":"Normal hizmete dönüş."},{"w":"resurgence","tr":"yeniden canlanma / diriliş","te":"Noun","tt":"İsim","de":"A situation in which something starts to happen again","dt":"Bir şeyin tekrar gerçekleşmeye (canlanmaya) başlaması","e1":"A resurgence of interest in old movies.","e1t":"Eski filmlere duyulan ilginin yeniden canlanması.","e2":"The resurgence of a disease.","e2t":"Bir hastalığın tekrar nüksetmesi (yayılması)."},{"w":"resuscitate","tr":"hayata döndürmek / diriltmek / canlandırmak","te":"Verb","tt":"Fiil","de":"To bring someone back to life or consciousness","dt":"Birini hayata veya bilince döndürmek","e1":"To resuscitate a drowning victim.","e1t":"Boğulmakta olan birini hayata döndürmek.","e2":"Efforts to resuscitate the economy.","e2t":"Ekonomiyi canlandırma çabaları."},{"w":"retainer","tr":"hizmetkar / ön ödeme / diş teli (pekiştirici)","te":"Noun","tt":"İsim","de":"A servant who has worked for a family for a long time; or a fee","dt":"Uzun süreli hizmetkar; veya (avukat vb. için) ön ödeme ücreti","e1":"An old family retainer.","e1t":"Eski bir aile hizmetkarı.","e2":"To pay a monthly retainer.","e2t":"Aylık sabit ücret (danışmanlık ücreti) ödemek."},{"w":"retentive","tr":"hafızası kuvvetli / tutucu / hapsedici","te":"Adjective","tt":"Sıfat","de":"Having the ability to store or keep something","dt":"Bir şeyi saklama veya tutma yeteneği olan","e1":"A retentive memory.","e1t":"Kuvvetli (hiç unutmayan) bir hafıza.","e2":"Retentive soil (holds water).","e2t":"Su tutan (geçirmeyen) toprak."},{"w":"retinue","tr":"maiyet / eşlik edenler","te":"Noun","tt":"İsim","de":"A group of people who travel with an important person","dt":"Önemli bir kişiyle birlikte seyahat eden grup","e1":"The king and his retinue.","e1t":"Kral ve maiyeti.","e2":"A large retinue of advisors.","e2t":"Kalabalık bir danışman grubu."},{"w":"retiring","tr":"çekingen / utangaç / emekli olan","te":"Adjective","tt":"Sıfat","de":"(Of a person) quiet and avoiding social activities","dt":"(Kişi için) sessiz ve sosyal ortamlardan kaçınan","e1":"A shy and retiring man.","e1t":"Utangaç ve çekingen bir adam.","e2":"The retiring president.","e2t":"Emekli olan (görevi devreden) başkan."},{"w":"retract","tr":"geri çekmek / sözünü geri almak","te":"Verb","tt":"Fiil","de":"To take back a statement or an offer; or to pull something back","dt":"Bir ifadeyi veya teklifi geri çekmek; veya bir şeyi içeri çekmek","e1":"He was forced to retract his comments.","e1t":"Yorumlarını geri çekmeye zorlandı.","e2":"The cat retracted its claws.","e2t":"Kedi pençelerini içeri çekti."},{"w":"retrench","tr":"masrafları kısmak / tasarrufa gitmek","te":"Verb","tt":"Fiil","de":"To reduce costs or spending in response to difficult conditions","dt":"Zor koşullar nedeniyle masrafları veya harcamaları azaltmak","e1":"The company had to retrench due to the recession.","e1t":"Şirket durgunluk nedeniyle masrafları kısmak zorunda kaldı.","e2":"To retrench on luxuries.","e2t":"Lüks harcamalardan tasarruf etmek."},{"w":"retribution","tr":"kısas / hak edilen ceza / intikam","te":"Noun","tt":"İsim","de":"Punishment that is deserved and severe","dt":"Hak edilmiş ve şiddetli ceza","e1":"Fear of divine retribution.","e1t":"İlahi ceza (azap) korkusu.","e2":"The victims are seeking retribution.","e2t":"Kurbanlar kısas (ceza) istiyorlar."},{"w":"retrograde","tr":"geriye giden / kötüleşen / ters","te":"Adjective","tt":"Sıfat","de":"Moving backward; or making a situation worse","dt":"Geriye giden; veya bir durumu daha kötüye götüren","e1":"A retrograde step.","e1t":"Geriye doğru bir adım (gerileme).","e2":"Retrograde motion of planets.","e2t":"Gezegenlerin geri hareketi (retro)."},{"w":"retrospective","tr":"geçmişe yönelik / retrospektif (sergi)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Looking back at past events; or an exhibition of an artist's whole work","dt":"Geçmiş olaylara bakma; veya bir sanatçının tüm eserlerini kapsayan sergi","e1":"A retrospective study.","e1t":"Geriye dönük (geçmişi inceleyen) bir çalışma.","e2":"A retrospective exhibition.","e2t":"Retrospektif sergi."},{"w":"revelry","tr":"eğlence / alem / cümbüş","te":"Noun","tt":"İsim","de":"Noisy and happy celebration, often involving drinking","dt":"Genellikle içki içeren, gürültülü ve mutlu kutlama","e1":"The sound of midnight revelry.","e1t":"Gece yarısı eğlencesinin sesi.","e2":"To join in the revelries.","e2t":"Eğlencelere katılmak."},{"w":"reverberate","tr":"yankılanmak / çınlamak / etkisini sürdürmek","te":"Verb","tt":"Fiil","de":"(Of a sound) to echo; or (of an event) to have a long","dt":"lasting effect","e1":"(Ses için) yankılanmak; veya (olay için) uzun süreli etki bırakmak","e1t":"Her voice reverberated through the hall.","e2":"Sesi salonun içinde yankılandı.","e2t":"The news reverberated around the world."},{"w":"revered","tr":"saygı duyulan / kutsal sayılan / aziz","te":"Adjective","tt":"Sıfat","de":"Very much respected and admired","dt":"Çok saygı duyulan ve hayran olunan","e1":"A revered spiritual leader.","e1t":"Saygın (yüce) bir ruhani lider.","e2":"He is revered as a national hero.","e2t":"Ulusal bir kahraman olarak saygı görüyor."},{"w":"reverie","tr":"hayal / hülya / dalgınlık","te":"Noun","tt":"İsim","de":"A state of being pleasantly lost in one's thoughts; a daydream","dt":"Düşüncelere dalıp gitme hali; hayal kurma","e1":"He was jolted out of his reverie by the phone.","e1t":"Telefon sesiyle hülyalarından (dalgınlığından) sıyrıldı.","e2":"To be lost in reverie.","e2t":"Hayale dalmak."},{"w":"revert","tr":"geri dönmek / eski haline dönmek","te":"Verb","tt":"Fiil","de":"To go back to a previous condition, habit, or subject","dt":"Önceki bir duruma, alışkanlığa veya konuya geri dönmek","e1":"The land reverted to desert.","e1t":"Toprak tekrar çöle dönüştü.","e2":"To revert to original plans.","e2t":"Orijinal planlara geri dönmek."},{"w":"revile","tr":"sövüp saymak / ağır eleştirmek / hakaret etmek","te":"Verb","tt":"Fiil","de":"To criticize someone strongly or say unpleasant things to them","dt":"Birini sertçe eleştirmek veya ona nahoş şeyler söylemek","e1":"He was reviled by the press.","e1t":"Basın tarafından ağır şekilde eleştirildi (yerden yere vuruldu).","e2":"To revile someone's name.","e2t":"Birinin adına leke sürmek (hakaret etmek)."},{"w":"revitalize / revitalise","tr":"canlandırmak / yeni bir soluk getirmek","te":"Verb","tt":"Fiil","de":"To give new life, energy, or success to something","dt":"Bir şeye yeni bir hayat, enerji veya başarı kazandırmak","e1":"To revitalize the city center.","e1t":"Şehir merkezini canlandırmak.","e2":"A plan to revitalize the economy.","e2t":"Ekonomiye yeni bir soluk getirme planı."},{"w":"revocation","tr":"iptal / fesih / geri alma","te":"Noun","tt":"İsim","de":"The act of stating officially that a law or agreement is no longer valid","dt":"Bir yasanın veya anlaşmanın artık geçerli olmadığını resmen bildirme","e1":"The revocation of a license.","e1t":"Bir lisansın (ehliyetin) iptali.","e2":"Revocation of a will.","e2t":"Vasiyetin feshi."},{"w":"rhapsodize / rhapsodise","tr":"ballandıra ballandıra anlatmak / övmek","te":"Verb","tt":"Fiil","de":"To speak or write with great enthusiasm and delight","dt":"Büyük bir heves ve sevinçle (coşkuyla) konuşmak veya yazmak","e1":"He rhapsodized about the beauty of the island.","e1t":"Adanın güzelliğini ballandıra ballandıra anlattı.","e2":"To rhapsodize over a new book.","e2t":"Yeni bir kitabı yere göğe sığdıramamak."},{"w":"ribald","tr":"müstehcen / kaba ve komik / açık saçık","te":"Adjective","tt":"Sıfat","de":"Relating to sexual matters in a rude but humorous way","dt":"Cinsel konularla ilgili kaba ama komik olan","e1":"Ribald jokes.","e1t":"Müstehcen şakalar.","e2":"Ribald laughter.","e2t":"Kaba ve yüksek sesli gülüşmeler."},{"w":"rife","tr":"yaygın / dolu / çok (genellikle kötü bir şey için)","te":"Adjective","tt":"Sıfat","de":"(Of something bad) very common or frequent","dt":"(Kötü bir şey için) çok yaygın veya sık","e1":"The city was rife with rumors.","e1t":"Şehir söylentilerle dolup taşıyordu.","e2":"Corruption is rife in the government.","e2t":"Hükümette yolsuzluk kol geziyor (çok yaygın)."},{"w":"rig","tr":"hile karıştırmak / kurmak / donatmak / sondaj kulesi","te":"Verb/Noun","tt":"Fiil/İsim","de":"To arrange something dishonestly; or to fit sails to a boat","dt":"Bir şeyi hileyle ayarlamak; veya bir tekneyi donatmak","e1":"To rig an election.","e1t":"Seçime hile karıştırmak.","e2":"Oil rig.","e2t":"Petrol sondaj kulesi."},{"w":"rigor / rigour","tr":"sertlik / titizlik / şiddet / katılık","te":"Noun","tt":"İsim","de":"The quality of being detailed, careful, and strict","dt":"Detaylı, dikkatli ve sıkı olma niteliği","e1":"Scientific rigor.","e1t":"Bilimsel titizlik.","e2":"The rigors of the winter.","e2t":"Kışın şiddeti (zorlukları)."},{"w":"rile","tr":"kızdırmak / sinirlendirmek / tepesini attırmak","te":"Verb","tt":"Fiil","de":"To make someone angry (informal)","dt":"Birini kızdırmak (informal)","e1":"His attitude really riled me.","e1t":"Onun tavrı beni gerçekten sinir etti.","e2":"Don't let him rile you.","e2t":"Seni kızdırmasına izin verme."},{"w":"rind","tr":"kabuk (meyve/peynir/pastırma)","te":"Noun","tt":"İsim","de":"The hard outer skin of some foods","dt":"Bazı gıdaların sert dış kabuğu","e1":"Orange rind.","e1t":"Portakal kabuğu.","e2":"Bacon rind.","e2t":"Pastırma derisi/kabuğu."},{"w":"riotous","tr":"gürültülü / taşkın / olaylı / renkli","te":"Adjective","tt":"Sıfat","de":"Noisy and uncontrolled; or very colorful","dt":"Gürültülü ve kontrolsüz; veya çok renkli","e1":"A riotous party.","e1t":"Taşkın (gürültülü) bir parti.","e2":"Riotous colors (vibrant).","e2t":"Cıvıl cıvıl (parlak) renkler."},{"w":"riveting","tr":"büyüleyici / sürükleyici / perçinleme","te":"Adjective","tt":"Sıfat","de":"Extremely interesting and exciting","dt":"Son derece ilginç ve heyecan verici","e1":"A riveting story.","e1t":"Sürükleyici bir hikaye.","e2":"Her performance was riveting.","e2t":"Performansı büyüleyiciydi."},{"w":"rococo","tr":"rokoko / aşırı süslü","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"An elaborate and highly decorated style of art/furniture","dt":"Sanat veya mobilyada aşırı detaylı ve süslü bir tarz","e1":"Rococo architecture.","e1t":"Rokoko mimarisi.","e2":"A rococo mirror.","e2t":"Aşırı süslü bir ayna."},{"w":"roster","tr":"liste / görev çizelgesi / kadro","te":"Noun","tt":"İsim","de":"A list of people's names and the jobs they have to do","dt":"İsim listesi ve yapılacak görevlerin çizelgesi","e1":"The duty roster.","e1t":"Nöbet çizelgesi.","e2":"To be on the roster.","e2t":"Listede yer almak."},{"w":"rostrum","tr":"kürsü / podyum / nutuk mahalli","te":"Noun","tt":"İsim","de":"A small platform on which a person stands to give a speech","dt":"Konuşma yapmak için üzerine çıkılan küçük platform","e1":"He stepped up to the rostrum.","e1t":"Kürsüye çıktı.","e2":"To speak from a rostrum.","e2t":"Podyumdan (kürsüden) konuşmak."},{"w":"rote","tr":"ezber / rutin / mekanik tekrar","te":"Noun","tt":"İsim","de":"Learning something by repeating it without thinking","dt":"Düşünmeden, tekrar ederek öğrenme (ezberleme)","e1":"To learn by rote.","e1t":"Ezbere öğrenmek.","e2":"Rote learning.","e2t":"Ezberci eğitim."},{"w":"rotund","tr":"yuvarlak / tombul / gür (ses)","te":"Adjective","tt":"Sıfat","de":"Round or fat; or (of a sound) deep and full","dt":"Yuvarlak veya tombul; veya (ses için) derin ve gür","e1":"A rotund little man.","e1t":"Tombul, ufak tefek bir adam.","e2":"Rotund tones.","e2t":"Dolgun (gür) tonlar."},{"w":"rout","tr":"bozguna uğratmak / darmadağın etmek / hezimet","te":"Verb/Noun","tt":"Fiil/İsim","de":"To defeat someone completely; or a total defeat","dt":"Birini tamamen yenmek; veya tam bir yenilgi","e1":"Our team routed the visitors.","e1t":"Takımımız misafirleri bozguna uğrattı.","e2":"The battle ended in a rout.","e2t":"Savaş bir hezimetle (bozgunla) bitti."},{"w":"rudimentary","tr":"temel / başlangıç düzeyinde / gelişmemiş","te":"Adjective","tt":"Sıfat","de":"Basic; or relating to an early stage of development","dt":"Temel; veya gelişimin erken evresiyle ilgili","e1":"Rudimentary knowledge.","e1t":"Başlangıç düzeyinde (temel) bilgi.","e2":"Rudimentary tools.","e2t":"İlkel (basit) aletler."},{"w":"rue","tr":"pişman olmak / üzülmek / sedef otu","te":"Verb/Noun","tt":"Fiil/İsim","de":"To feel sorry about something (literary)","dt":"Bir şey için pişmanlık duymak (edebi)","e1":"He will live to rue the day he met her.","e1t":"Onunla tanıştığı güne lanet edecek (pişman olacak).","e2":"Rueful (adjective).","e2t":"Pişman / kederli."},{"w":"ruffian","tr":"haydut / serseri / kabadayı","te":"Noun","tt":"İsim","de":"A violent and cruel man","dt":"Şiddet yanlısı ve zalim adam","e1":"A gang of ruffians.","e1t":"Bir serseri çetesi.","e2":"He was attacked by ruffians.","e2t":"Haydutların saldırısına uğradı."},{"w":"ruminate","tr":"üzerinde uzun uzun düşünmek / geviş getirmek","te":"Verb","tt":"Fiil","de":"To think carefully and deeply about something; or (of cows) to chew food again","dt":"Bir şey üzerinde derinlemesine düşünmek; veya (inek vb.) geviş getirmek","e1":"He ruminated on the meaning of life.","e1t":"Hayatın anlamı üzerine kafa yordu (derin derin düşündü).","e2":"Ruminant animals.","e2t":"Geviş getiren hayvanlar."},{"w":"rummage","tr":"altını üstüne getirmek / aramak / kurcalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To search for something by moving things around carelessly","dt":"Eşyaları karıştırarak bir şeyi aramak","e1":"She rummaged through her bag for her keys.","e1t":"Anahtarları için çantasının altını üstüne getirdi.","e2":"To have a rummage in the attic.","e2t":"Tavan arasını kurcalamak."},{"w":"saccharine","tr":"aşırı tatlı / yapmacık derecede nazik / sakarin","te":"Adjective","tt":"Sıfat","de":"Too sweet or too polite in a way that is not sincere","dt":"Samimi olmayacak kadar tatlı veya nazik","e1":"A saccharine smile.","e1t":"Yapmacık (vıcık vıcık) bir gülümseme.","e2":"Saccharine sentimentality.","e2t":"Aşırı (baygın) duygusallık."},{"w":"sacrilegious","tr":"kutsala saygısız / dince yasak olan","te":"Adjective","tt":"Sıfat","de":"Showing a lack of respect for something holy","dt":"Kutsal bir şeye saygısızlık gösteren","e1":"A sacrilegious act.","e1t":"Kutsala saygısızlık içeren eylem.","e2":"Sacrilegious behavior.","e2t":"Sapkınca davranış."},{"w":"sacrosanct","tr":"çok kutsal / dokunulmaz / tartışılmaz","te":"Adjective","tt":"Sıfat","de":"Thought to be too important or holy to be changed","dt":"Değiştirilemeyecek kadar önemli veya kutsal olduğu düşünülen","e1":"A sacrosanct tradition.","e1t":"Dokunulmaz (çok kutsal) bir gelenek.","e2":"To treat someone's privacy as sacrosanct.","e2t":"Birinin mahremiyetini dokunulmaz kabul etmek."},{"w":"sadistic","tr":"sadist / eziyetten zevk alan","te":"Adjective","tt":"Sıfat","de":"Getting pleasure from causing pain to others","dt":"Başkalarına acı çektirmekten zevk alan","e1":"A sadistic guard.","e1t":"Sadist bir gardiyan.","e2":"Sadistic pleasure.","e2t":"Sadistçe bir zevk."},{"w":"sagacious","tr":"öngörülü / zeki / akıllıca / ferasetli","te":"Adjective","tt":"Sıfat","de":"Having or showing understanding and the ability to make good judgments","dt":"Anlayış ve iyi muhakeme yeteneğine sahip olan veya gösteren","e1":"A sagacious advisor.","e1t":"Ferasetli (bilge) bir danışman.","e2":"A sagacious decision.","e2t":"Akıllıca (sağduyulu) bir karar."},{"w":"salacious","tr":"müstehcen / şehvet uyandıran / açık saçık","te":"Adjective","tt":"Sıfat","de":"Causing or showing too much interest in sexual matters","dt":"Cinsel konulara aşırı ilgi gösteren veya uyandıran","e1":"Salacious gossip.","e1t":"Müstehcen dedikodu.","e2":"Salacious details of the scandal.","e2t":"Skandalın açık saçık detayları."},{"w":"salubrious","tr":"sağlığa yararlı / şifalı / ferah","te":"Adjective","tt":"Sıfat","de":"(Of a place) pleasant, clean, and healthy to live in","dt":"(Yer için) hoş, temiz ve sağlıklı","e1":"A salubrious climate.","e1t":"Sağlıklı (şifalı) bir iklim.","e2":"Not a very salubrious neighborhood.","e2t":"Pek de nezih (temiz/sağlıklı) olmayan bir mahalle."},{"w":"salutary","tr":"faydalı / ders verici / yararlı","te":"Adjective","tt":"Sıfat","de":"(Of an experience) causing improvement of behavior or character","dt":"(Deneyim için) davranış veya karakterde iyileşmeye neden olan","e1":"A salutary lesson.","e1t":"İbret verici (faydalı) bir ders.","e2":"The effects of the new law were salutary.","e2t":"Yeni yasanın etkileri yararlı oldu."},{"w":"sanctimonious","tr":"kutsallık taslayan / yapmacık dindar / riyakar","te":"Adjective","tt":"Sıfat","de":"Acting as if you are morally better than others","dt":"Ahlaken diğerlerinden üstünmüş gibi davranan","e1":"A sanctimonious tone.","e1t":"Kutsallık taslayan bir ton.","e2":"I'm tired of his sanctimonious lectures.","e2t":"Onun ahlak dersi veren yapmacık tavırlarından bıktım."},{"w":"sanguine","tr":"iyimser / umutlu / kanlı (yüz)","te":"Adjective","tt":"Sıfat","de":"Positive and hoping for good things, even in a difficult situation","dt":"Zor bir durumda bile olumlu ve umutlu olan","e1":"He is sanguine about the company's future.","e1t":"Şirketin geleceği konusunda iyimserdir.","e2":"A sanguine complexion.","e2t":"Kanlı canlı (sağlıklı kırmızı) bir beniz."},{"w":"sapient","tr":"bilge / akıllı / zeki","te":"Adjective","tt":"Sıfat","de":"Wise or attempting to appear wise (formal)","dt":"Bilge veya bilge görünmeye çalışan (resmi)","e1":"A sapient observation.","e1t":"Bilgece (zekice) bir gözlem.","e2":"Homo sapiens.","e2t":"Akıllı insan (tür adı)."},{"w":"sardonic","tr":"alaycı / küçümseyici / acımasızca alay eden","te":"Adjective","tt":"Sıfat","de":"Showing that you think you are better than other people","dt":"Diğerlerinden daha iyi olduğunu düşündüğünü gösteren (alaycı)","e1":"A sardonic smile.","e1t":"Alaycı (acımasız) bir gülümseme.","e2":"A sardonic sense of humor.","e2t":"Küçümseyici (sert) bir mizah anlayışı."},{"w":"satiate","tr":"doyurmak / bıktırmak / gına getirmek","te":"Verb","tt":"Fiil","de":"To completely satisfy a desire or need","dt":"Bir arzuyu veya ihtiyacı tamamen tatmin etmek","e1":"Nothing could satiate his hunger for power.","e1t":"Hiçbir şey onun güç hırsını doyuramazdı.","e2":"To be satiated with food.","e2t":"Yemeğe doymuş (tıka basa doymuş) olmak."},{"w":"savory / savoury","tr":"lezzetli / iştah açıcı / tuzlu","te":"baharatlı (yemek)","tt":"Adjective","de":"Sıfat","dt":"Pleasant to eat; or salty or spicy rather than sweet","e1":"Yemesi hoş; veya tatlıdan ziyade tuzlu/baharatlı","e1t":"A savory snack.","e2":"Tuzlu (iştah açıcı) bir atıştırmalık.","e2t":"Savory dishes."},{"w":"scamper","tr":"koşuşturmak / seğirtmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To run with quick light steps, especially through fear or excitement","dt":"Özellikle korku veya heyecanla hızlı adımlarla koşmak","e1":"The children scampered across the garden.","e1t":"Çocuklar bahçede koşuşturdular.","e2":"Scamper away.","e2t":"Hızla kaçmak."},{"w":"scanty","tr":"yetersiz / az / dar (giysi)","te":"Adjective","tt":"Sıfat","de":"Very small in amount; or (of clothes) small and thin","dt":"Miktar olarak çok az; veya (giysi için) dar ve ince","e1":"Scanty evidence.","e1t":"Yetersiz (az) kanıt.","e2":"Scanty vegetation.","e2t":"Cılız bitki örtüsü."},{"w":"scathing","tr":"sert / yıkıcı / iğneleyici (eleştiri)","te":"Adjective","tt":"Sıfat","de":"Criticizing someone or something in a severe and unkind way","dt":"Birini veya bir şeyi sert ve kaba bir şekilde eleştiren","e1":"A scathing attack on the government.","e1t":"Hükümete yönelik yıkıcı (sert) bir saldırı.","e2":"Scathing remarks.","e2t":"İğneleyici sözler."},{"w":"schism","tr":"bölünme / ayrılık (özellikle dini/siyasi)","te":"Noun","tt":"İsim","de":"A division into two groups because of a disagreement","dt":"Bir anlaşmazlık nedeniyle iki gruba bölünme","e1":"A schism in the church.","e1t":"Kilisede bir bölünme (ayrılık).","e2":"To cause a schism.","e2t":"Bölünmeye yol açmak."},{"w":"scintilla","tr":"zerre / eser / kırıntı","te":"Noun","tt":"İsim","de":"A very small amount of something (formal)","dt":"Bir şeyin çok küçük miktarı (resmi)","e1":"Not a scintilla of evidence.","e1t":"En ufak bir kanıt (zerresi) bile yok.","e2":"A scintilla of hope.","e2t":"Bir umut kırıntısı."},{"w":"scion","tr":"filiz / oğul / soy / varis","te":"Noun","tt":"İsim","de":"A young member of a rich or famous family","dt":"Zengin veya ünlü bir ailenin genç üyesi (varisi)","e1":"The scion of a wealthy banking family.","e1t":"Zengin bir bankacı ailesinin varisi (oğlu).","e2":"A scion of the royal house.","e2t":"Kraliyet ailesinin bir ferdi."},{"w":"scoff","tr":"alay etmek / küçümsemek / mideye indirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh at someone with no respect; or to eat a lot quickly","dt":"Birine saygısızca gülmek; veya çok şeyi hızla yemek","e1":"They scoffed at his ideas.","e1t":"Onun fikirleriyle alay ettiler.","e2":"He scoffed the whole cake.","e2t":"Tüm keki mideye indirdi (hızla yedi)."},{"w":"scrupulous","tr":"çok titiz / dürüst / vicdanlı","te":"Adjective","tt":"Sıfat","de":"Extremely honest; or paying great attention to details","dt":"Son derece dürüst; veya detaylara büyük özen gösteren","e1":"Scrupulous attention to detail.","e1t":"Detaylara gösterilen titiz dikkat.","e2":"A scrupulous politician.","e2t":"Dürüst (vicdanlı) bir siyasetçi."},{"w":"scrutinize / scrutinise","tr":"ince eleyip sık dokumak / dikkatle incelemek","te":"Verb","tt":"Fiil","de":"To examine something very carefully","dt":"Bir şeyi çok dikkatli bir şekilde incelemek","e1":"The police scrutinized the evidence.","e1t":"Polis kanıtları dikkatle inceledi (didik didik etti).","e2":"To be scrutinized by the media.","e2t":"Medya tarafından mercek altına alınmak."},{"w":"scuttle","tr":"batırmak (kendi gemisini) / hızlıca kaçmak / suya düşürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To sink a ship intentionally; or to run with small quick steps","dt":"Bir gemiyi kasten batırmak; veya küçük hızlı adımlarla koşmak","e1":"To scuttle a plan.","e1t":"Bir planı suya düşürmek (bozmak).","e2":"He scuttled away when he saw us.","e2t":"Bizi görünce hızla kaçtı (sıvıştı)."},{"w":"seclude","tr":"inzivaya çekmek / ayırmak / gizlemek","te":"Verb","tt":"Fiil","de":"To keep someone away from other people","dt":"Birini diğer insanlardan uzak tutmak","e1":"To seclude oneself in the countryside.","e1t":"Kırsalda inzivaya çekilmek.","e2":"A secluded beach (private).","e2t":"Gözlerden uzak (ıssız) bir plaj."},{"w":"sectarian","tr":"mezhepçi / dar görüşlü / hizipçi","te":"Adjective","tt":"Sıfat","de":"Relating to the differences between different religions","dt":"Farklı dinler/mezhepler arasındaki ayrılıklarla ilgili","e1":"Sectarian violence.","e1t":"Mezhep çatışması (şiddeti).","e2":"Sectarian interests.","e2t":"Hizipçi (dar) çıkarlar."},{"w":"sedentary","tr":"yerleşik / oturarak yapılan / hareketsiz","te":"Adjective","tt":"Sıfat","de":"Involving little exercise or physical activity","dt":"Az egzersiz veya fiziksel aktivite içeren","e1":"A sedentary lifestyle.","e1t":"Hareketsiz (oturarak geçen) bir yaşam tarzı.","e2":"A sedentary job.","e2t":"Masa başı (oturarak yapılan) iş."},{"w":"sedition","tr":"halkı isyana teşvik / fitne","te":"Noun","tt":"İsim","de":"Language or behavior that encourages people to rebel","dt":"İnsanları isyana teşvik eden dil veya davranış","e1":"He was charged with sedition.","e1t":"Halkı isyana teşvikle suçlandı.","e2":"Seditious writings.","e2t":"Fitne çıkaran (isyana teşvik eden) yazılar."},{"w":"sedulous","tr":"çalışkan / gayretli / titiz","te":"Adjective","tt":"Sıfat","de":"Showing great care and effort in your work","dt":"İşinde büyük özen ve çaba gösteren","e1":"Sedulous attention to duties.","e1t":"Görevlere gösterilen titiz ilgi.","e2":"A sedulous student.","e2t":"Gayretli bir öğrenci."},{"w":"seethe","tr":"kaynamak / öfkeden kudurmak / kaynaşmak","te":"Verb","tt":"Fiil","de":"To be extremely angry; or to move around in large numbers","dt":"Aşırı öfkeli olmak; veya (kalabalık için) kaynaşmak","e1":"He was seething with rage.","e1t":"Öfkeden kuduruyordu (içten içe kaynıyordu).","e2":"The streets were seething with people.","e2t":"Sokaklar insan kaynıyordu."},{"w":"semantics","tr":"anlambilim / semantik","te":"Noun","tt":"İsim","de":"The study of the meanings of words and phrases","dt":"Kelime ve ifadelerin anlamlarının incelenmesi","e1":"Let's not argue over semantics.","e1t":"Kelime oyunları (anlamlar) üzerinden tartışmayalım.","e2":"Semantic change.","e2t":"Anlam değişmesi."},{"w":"semblance","tr":"benzerlik / görünüş / eser","te":"Noun","tt":"İsim","de":"A situation in which something seems to exist","dt":"Bir şeyin var gibi göründüğü durum","e1":"To restore some semblance of order.","e1t":"Bir nebze de olsa düzen (görünüşü) sağlamak.","e2":"He managed a semblance of a smile.","e2t":"Gülümsemeye benzer bir ifade takınmayı başardı."},{"w":"seminal","tr":"ufuk açıcı / çığır açan / temel / sperm ile ilgili","te":"Adjective","tt":"Sıfat","de":"Containing important new ideas and having a great influence","dt":"Önemli yeni fikirler içeren ve büyük etkisi olan","e1":"A seminal work of literature.","e1t":"Edebiyatın ufuk açıcı (temel) bir eseri.","e2":"Seminal fluid.","e2t":"Semen (ersuyu)."},{"w":"senescence","tr":"yaşlanma / ihtiyarlama","te":"Noun","tt":"İsim","de":"The physical decline that happens with age (formal)","dt":"Yaşla birlikte meydana gelen fiziksel gerileme (resmi)","e1":"Cellular senescence.","e1t":"Hücresel yaşlanma.","e2":"The onset of senescence.","e2t":"Yaşlılığın başlangıcı."},{"w":"sensual","tr":"şehvetli / duyusal / bedensel hazla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to physical pleasure","dt":"Fiziksel hazla ilgili","e1":"Sensual pleasures.","e1t":"Bedensel (şehvetli) zevkler.","e2":"A sensual dance.","e2t":"Şehvetli bir dans. (Not: 'Sensuous' daha çok estetik duyularla, 'Sensual' ise daha çok cinsel hazla ilgilidir)."},{"w":"sentinel","tr":"nöbetçi / gözcü","te":"Noun","tt":"İsim","de":"A person who stands and keeps watch","dt":"Durup izleyen/gözleyen kişi (nöbetçi)","e1":"The sentinels at the palace gate.","e1t":"Saray kapısındaki nöbetçiler.","e2":"To act as a sentinel.","e2t":"Gözcülük yapmak."},{"w":"sepulcher / sepulchre","tr":"mezar / türbe / kabir","te":"Noun","tt":"İsim","de":"A stone structure where someone is buried","dt":"Birinin gömüldüğü taş yapı (mezar)","e1":"The holy sepulcher.","e1t":"Kutsal kabir.","e2":"A marble sepulcher.","e2t":"Mermer türbe."},{"w":"serendipity","tr":"mutlu tesadüf / şans eseri bulma","te":"Noun","tt":"İsim","de":"Finding interesting or valuable things by chance","dt":"İlginç veya değerli şeyleri tesadüfen bulma","e1":"By a stroke of serendipity.","e1t":"Tamamen mutlu bir tesadüf eseri.","e2":"The discovery was a result of serendipity.","e2t":"Keşif, bir tesadüfün sonucuydu."},{"w":"servile","tr":"kölece / dalkavukça / zillet içinde","te":"Adjective","tt":"Sıfat","de":"Too eager to serve and please someone","dt":"Birine hizmet etmeye ve onu memnun etmeye aşırı istekli","e1":"A servile attitude.","e1t":"Kölece (yaltakçı) bir tavır.","e2":"Servile imitation.","e2t":"Maymunca (kölece) taklit."},{"w":"severance","tr":"ilişkiyi kesme / kopma / kıdem tazminatı","te":"Noun","tt":"İsim","de":"The act of ending a connection or relationship","dt":"Bir bağlantıyı veya ilişkiyi sona erdirme eylemi","e1":"The severance of diplomatic ties.","e1t":"Diplomatik ilişkilerin kesilmesi.","e2":"Severance pay.","e2t":"Kıdem (işten ayrılma) tazminatı."},{"w":"shackle","tr":"kelepçelemek / engellemek / pranga","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put chains around someone's hands or feet","dt":"Birinin ellerine veya ayaklarına zincir vurmak","e1":"To be shackled to one's desk.","e1t":"Masasına bağlanmış (mahkum) olmak.","e2":"The shackles of tradition.","e2t":"Geleneğin prangaları (engelleri)."},{"w":"sheaf","tr":"demet / deste / yığın","te":"Noun","tt":"İsim","de":"A number of things, especially papers or wheat, tied together","dt":"Bir araya getirilmiş şeyler (özellikle kağıt veya buğday)","e1":"A sheaf of papers.","e1t":"Bir deste kağıt.","e2":"Sheaves of wheat.","e2t":"Buğday demetleri."},{"w":"shimmer","tr":"parıldamak / ışıldamak / titrek ışık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To shine with a soft light that seems to shake slightly","dt":"Hafifçe titriyormuş gibi görünen yumuşak bir ışıkla parlamak","e1":"The sea shimmered in the moonlight.","e1t":"Deniz ay ışığında parlıyordu.","e2":"A shimmer of heat over the road.","e2t":"Yolun üzerinde titreyen sıcaklık dalgası."},{"w":"shirk","tr":"kaytarmak / kaçınmak / yan çizmek","te":"Verb","tt":"Fiil","de":"To avoid work, duties, or responsibilities","dt":"İşten, görevden veya sorumluluktan kaçınmak","e1":"He never shirks his duties.","e1t":"Görevlerinden asla kaçmaz (kaytarmaz).","e2":"To shirk responsibility.","e2t":"Sorumluluktan yan çizmek."},{"w":"shroud","tr":"örtmek / gizlemek / kefen","te":"Noun/Verb","tt":"İsim/Fiil","de":"A cloth used to wrap a dead body; or to hide something","dt":"Ölüyü sarmak için kullanılan örtü; veya bir şeyi gizlemek","e1":"The mountains were shrouded in mist.","e1t":"Dağlar sisle örtülmüştü (sisin içinde kaybolmuştu).","e2":"Shrouded in mystery.","e2t":"Gizemle perdelenmiş (sırlarla dolu)."},{"w":"shyster","tr":"düzenbaz avukat / dolandırıcı politikacı","te":"Noun","tt":"İsim","de":"A person (especially a lawyer) who uses dishonest methods","dt":"Dürüst olmayan yöntemler kullanan kişi (özellikle avukat)","e1":"Don't trust that shyster!","e1t":"O düzenbaza güvenme!","e2":"A shyster lawyer.","e2t":"Düzenbaz (dalavereci) avukat."},{"w":"sibling","tr":"kardeş","te":"Noun","tt":"İsim","de":"A brother or sister","dt":"Erkek veya kız kardeş","e1":"Do you have any siblings?","e1t":"Hiç kardeşin var mı?","e2":"Sibling rivalry.","e2t":"Kardeşler arası rekabet."},{"w":"sibylline","tr":"kehanet niteliğinde / gizemli / kapalı","te":"Adjective","tt":"Sıfat","de":"Mysterious; having a hidden meaning (prophetic)","dt":"Gizemli; gizli bir anlamı olan (kehanet gibi)","e1":"Sibylline oracles.","e1t":"Gizemli kehanetler.","e2":"Her sibylline warnings.","e2t":"Onun ne anlama geldiği tam çözülemeyen (gizemli) uyarıları."},{"w":"sidereal","tr":"yıldızlarla ilgili / yıldızlara göre (zaman)","te":"Adjective","tt":"Sıfat","de":"Relating to the distant stars or their apparent positions","dt":"Uzak yıldızlarla veya onların görünür konumlarıyla ilgili","e1":"A sidereal year.","e1t":"Yıldız yılı.","e2":"Sidereal time.","e2t":"Yıldız zamanı."},{"w":"simian","tr":"maymuna benzer / maymunsu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to or resembling monkeys or apes","dt":"Maymunlarla ilgili veya maymuna benzeyen","e1":"Simian features.","e1t":"Maymunsu yüz hatları.","e2":"Simian virus.","e2t":"Maymun virüsü."},{"w":"simper","tr":"yapmacık gülümsemek / sırıtmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To smile in a silly or annoying way","dt":"Aptalca veya sinir bozucu şekilde (yapmacık) gülümsemek","e1":"She simpered at him.","e1t":"Ona yapmacık bir şekilde sırıttı.","e2":"A silly simper.","e2t":"Aptalca bir sırıtış."},{"w":"simulacrum","tr":"kopya / taklit / benzer","te":"Noun","tt":"İsim","de":"Something that looks like something else, especially a bad copy","dt":"Başka bir şeye benzeyen şey, özellikle (kalitesiz) taklit","e1":"A simulacrum of the original painting.","e1t":"Orijinal tablonun bir kopyası (benzeri).","e2":"The city was a simulacrum of its former self.","e2t":"Şehir eski halinin bir taklidi gibiydi."},{"w":"sinecure","tr":"yan gelip yatma işi / ballı maaşlı hafif iş","te":"Noun","tt":"İsim","de":"A position which involves little work but provides an income","dt":"Çok az iş gerektiren ama gelir sağlayan makam/mevki","e1":"The job was a complete sinecure.","e1t":"İş tam bir yan gelip yatma yeriydi.","e2":"To enjoy a sinecure.","e2t":"Zahmetsiz bir makamın tadını çıkarmak."},{"w":"sinewy","tr":"kaslı / adaleli / güçlü","te":"Adjective","tt":"Sıfat","de":"With strong muscles and little fat","dt":"Güçlü kasları olan ve yağsız (çevik)","e1":"The sinewy arms of a blacksmith.","e1t":"Bir demircinin adaleli (kaslı) kolları.","e2":"A sinewy body.","e2t":"Kaslı ve fit bir vücut."},{"w":"sinuous","tr":"kıvrımlı / bükülmüş / dolambaçlı","te":"Adjective","tt":"Sıfat","de":"Moving in a twisting or curving way","dt":"Bükülerek veya kıvrılarak hareket eden","e1":"The sinuous movements of a snake.","e1t":"Bir yılanın kıvrımlı hareketleri.","e2":"A sinuous path through the forest.","e2t":"Ormanda dolambaçlı bir yol."},{"w":"skiff","tr":"küçük sandal / kayık","te":"Noun","tt":"İsim","de":"A small boat for only one person","dt":"Tek kişilik küçük tekne/sandal","e1":"To row a skiff.","e1t":"Bir sandalla kürek çekmek.","e2":"A fishing skiff.","e2t":"Küçük balıkçı kayığı."},{"w":"skimp","tr":"kısmak / esirgemek / idareli kullanmak","te":"Verb","tt":"Fiil","de":"To use less of something than is needed","dt":"İhtiyaç olandan daha azını kullanmak (kısıntı yapmak)","e1":"Don't skimp on the butter!","e1t":"Tereyağından kısma!","e2":"To skimp on quality.","e2t":"Kaliteden ödün vermek (esirgemek)."},{"w":"skirmish","tr":"küçük çatışma / arbede / sürtüşme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short fight between small groups of soldiers","dt":"Küçük askeri gruplar arasındaki kısa süreli çatışma","e1":"Border skirmishes.","e1t":"Sınır çatışmaları.","e2":"A minor skirmish between protestors and police.","e2t":"Protestocular ve polis arasında küçük bir arbede."},{"w":"skittish","tr":"ürkek / oynak / havai","te":"Adjective","tt":"Sıfat","de":"(Of a horse) easily excited or frightened; or nervous","dt":"(At için) kolay heyecanlanan/ürkek; veya gergin/kararsız","e1":"A skittish horse.","e1t":"Ürkek bir at.","e2":"Investors are feeling skittish.","e2t":"Yatırımcılar kendilerini gergin (kararsız) hissediyorlar."},{"w":"skulduggery","tr":"dalavere / hilekarlık / sahtekarlık","te":"Noun","tt":"İsim","de":"Dishonest behavior or activities (informal)","dt":"Dürüst olmayan davranışlar veya faaliyetler","e1":"Political skulduggery.","e1t":"Siyasi dalavere.","e2":"Financial skulduggery.","e2t":"Finansal sahtekarlık."},{"w":"slacken","tr":"gevşetmek / yavaşlatmak / hafiflemek","te":"Verb","tt":"Fiil","de":"To become or make something less tight or less active","dt":"Daha az sıkı veya daha az aktif hale getirmek/gelmek","e1":"The rope slackened.","e1t":"İp gevşedi.","e2":"To slacken one's pace.","e2t":"Adımlarını yavaşlatmak."},{"w":"slake","tr":"gidermek (susuzluk/merak) / dindirmek","te":"Verb","tt":"Fiil","de":"To satisfy a feeling of being thirsty or wanting something","dt":"Susuzluk hissini veya bir isteği tatmin etmek (gidermek)","e1":"To slake your thirst with cold water.","e1t":"Susuzluğunu soğuk suyla gidermek.","e2":"To slake a curiosity.","e2t":"Merakını dindirmek."},{"w":"slapstick","tr":"kaba komedi / vurmalı","te":"kırmalı şaka","tt":"Noun/Adjective","de":"İsim/Sıfat","dt":"A type of humor based on simple physical actions","e1":"Basit fiziksel hareketlere (düşme, vurma) dayalı mizah türü","e1t":"Slapstick comedy.","e2":"Kaba komedi.","e2t":"The movie is full of slapstick humor."},{"w":"slatternly","tr":"pasaklı / kirli / kılık kıyafeti bozuk","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Untidy and dirty (usually of a woman)","dt":"Düzensiz ve kirli (genellikle kadın için kullanılır)","e1":"A slatternly appearance.","e1t":"Pasaklı bir görünüm.","e2":"To live in a slatternly way.","e2t":"Pasaklı bir şekilde yaşamak."},{"w":"sleazy","tr":"pespaye / adi / kirli ve nahoş","te":"Adjective","tt":"Sıfat","de":"Dirty, cheap, and not socially acceptable","dt":"Kirli, ucuz ve toplumsal olarak pek kabul görmeyen","e1":"A sleazy bar.","e1t":"Pespaye (tekin olmayan) bir bar.","e2":"Sleazy politicians.","e2t":"Adi (dürüst olmayan) siyasetçiler."},{"w":"sleeper","tr":"yataklı vagon / uyuyan (beklenmedik başarı) / uyuyan hücre","te":"Noun","tt":"İsim","de":"A train with beds; or something that becomes successful after a long time","dt":"Yataklı tren; veya uzun süre sonra başarıya ulaşan şey","e1":"The movie was a sleeper hit.","e1t":"Film başta ilgi görmedi ama sonra patladı (sleeper hit).","e2":"Sleeper cell (terrorist).","e2t":"Uyuyan hücre."},{"w":"slither","tr":"sürünmek / kaymak (yılan gibi)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To move smoothly over a surface like a snake","dt":"Bir yüzey üzerinde yılan gibi pürüzsüzce hareket etmek","e1":"The snake slithered across the sand.","e1t":"Yılan kumun üzerinde süzülerek (sürünerek) gitti.","e2":"To slither down a slope.","e2t":"Bir yamaçtan aşağı kaymak."},{"w":"sloth","tr":"tembellik / miskinlik / tembel hayvan","te":"Noun","tt":"İsim","de":"The state of being lazy; or a slow","dt":"moving animal","e1":"Tembellik durumu; veya yavaş hareket eden hayvan","e1t":"Spiritual sloth.","e2":"Ruhani miskinlik.","e2t":"The three"},{"w":"slough","tr":"derisini dökmek / kurtulmak / bataklık","te":"Verb/Noun","tt":"Fiil/İsim","de":"To get rid of skin; or to get rid of something unwanted","dt":"Deri dökmek; veya istenmeyen bir şeyden kurtulmak","e1":"A snake sloughs its skin.","e1t":"Yılan derisini döker.","e2":"To slough off old habits.","e2t":"Eski alışkanlıklardan kurtulmak (onları üzerinden atmak)."},{"w":"slovenly","tr":"pasaklı / baştan savma / düzensiz","te":"Adjective","tt":"Sıfat","de":"Untidy and dirty in appearance; or careless","dt":"Görünüşte kirli ve düzensiz; veya dikkatsiz","e1":"Slovenly habits.","e1t":"Pasaklı alışkanlıklar.","e2":"A slovenly piece of work.","e2t":"Baştan savma yapılmış bir iş."},{"w":"sluggish","tr":"yavaş / ağırkanlı / durgun","te":"Adjective","tt":"Sıfat","de":"Moving or operating more slowly than usual","dt":"Normalden daha yavaş hareket eden veya işleyen","e1":"A sluggish economy.","e1t":"Durgun bir ekonomi.","e2":"I felt sluggish after the heavy meal.","e2t":"Ağır yemekten sonra kendimi ağırkanlı (miskin) hissettim."},{"w":"sluice","tr":"kanal / su bendi / suyla yıkamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A passage for water with a gate; or to wash with water","dt":"Kapaklı su geçidi; veya bol suyla yıkamak","e1":"To open the sluice gates.","e1t":"Su bentlerini açmak.","e2":"To sluice the deck of a ship.","e2t":"Geminin güvertesini suyla yıkamak."},{"w":"smattering","tr":"yarım yamalak bilgi / az miktar","te":"Noun","tt":"İsim","de":"A very small amount of a subject that you know","dt":"Bir konu hakkında sahip olunan çok az (yüzeysel) bilgi","e1":"He has a smattering of French.","e1t":"Yarım yamalak bir Fransızcası var.","e2":"A smattering of applause.","e2t":"Zayıf (tek tük) bir alkış."},{"w":"smirk","tr":"sırıtmak / bıyık altından gülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To smile in a self","dt":"satisfied or silly way","e1":"Kendinden memnun veya aptalca bir şekilde gülümsemek","e1t":"He had a self","e2":"satisfied smirk on his face.","e2t":"Yüzünde kendinden emin, itici bir sırıtış vardı."},{"w":"smolder / smoulder","tr":"içten içe yanmak / tütmek / (duygu) gizlice sürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To burn slowly with smoke but no flame; or to exist secretly","dt":"Alevsiz, duman çıkararak yavaşça yanmak; veya (duygu) gizlice sürmek","e1":"The fire was still smoldering in the morning.","e1t":"Ateş sabah hala tütüyordu.","e2":"Smoldering resentment.","e2t":"İçten içe büyüyen (gizli) kırgınlık."},{"w":"snivel","tr":"burnunu çekerek ağlamak / sızlanmak","te":"Verb","tt":"Fiil","de":"To cry and complain in a way that is annoying","dt":"Rahatsız edici bir şekilde ağlayıp sızlanmak","e1":"Stop sniveling and tell me what happened!","e1t":"Sızlanmayı bırak da ne olduğunu anlat!","e2":"A sniveling child.","e2t":"Burnunu çekip ağlayan çocuk."},{"w":"sobriety","tr":"ayıklık / ciddiyet / ağırbaşlılık","te":"Noun","tt":"İsim","de":"The state of not being drunk; or being serious and calm","dt":"Sarhoş olmama durumu; veya ciddi ve sakin olma","e1":"He was tested for sobriety.","e1t":"Alkollü olup olmadığı (ayıklığı) test edildi.","e2":"To maintain one's sobriety.","e2t":"Ayıklığını korumak (alkolden uzak durmak)."},{"w":"societal","tr":"toplumsal / topluma dair","te":"Adjective","tt":"Sıfat","de":"Relating to the organization of a society","dt":"Toplumun yapısı veya organizasyonu ile ilgili","e1":"Societal changes.","e1t":"Toplumsal değişimler.","e2":"Societal pressures.","e2t":"Toplumsal baskılar."},{"w":"sojourn","tr":"kısa süreli kalmak / misafirlik / konaklama","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short period when a person stays in a particular place","dt":"Bir yerde geçirilen kısa süre (konaklama)","e1":"My brief sojourn in Paris.","e1t":"Paris'teki kısa konaklamam.","e2":"To sojourn in a foreign land.","e2t":"Yabancı bir yerde bir süre kalmak."},{"w":"solace","tr":"teselli / avuntu / rahatlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Help and comfort when you are feeling sad","dt":"Üzgünken alınan yardım ve rahatlama (teselli)","e1":"To find solace in music.","e1t":"Müzikte teselli bulmak.","e2":"His presence was a great solace to her.","e2t":"Onun varlığı ona büyük bir teselliydi."},{"w":"solicit","tr":"istemek / talep etmek / (müşteri) ayarlamaya çalışmak","te":"Verb","tt":"Fiil","de":"To ask someone for money, information, or help","dt":"Birinden para, bilgi veya yardım istemek","e1":"To solicit donations for charity.","e1t":"Hayır kurumu için bağış toplamak (istemek).","e2":"Prostitutes soliciting on the streets.","e2t":"Sokakta müşteri arayan (fahişeler)."},{"w":"solicitous","tr":"ilgili / özenli / endişeli (başkası için)","te":"Adjective","tt":"Sıfat","de":"Showing care and helpful attention to someone","dt":"Birine karşı ilgili ve özenli davranan","e1":"A solicitous host.","e1t":"İlgili (konuksever) bir ev sahibi.","e2":"She was very solicitous about my health.","e2t":"Sağlığım konusunda çok ilgiliydi."},{"w":"soliloquy","tr":"tirat / kendi kendine konuşma (sahne)","te":"Noun","tt":"İsim","de":"A speech in a play that the character speaks to himself","dt":"Oyunda bir karakterin kendi kendine yaptığı konuşma","e1":"Hamlet's famous soliloquy.","e1t":"Hamlet'in meşhur tiradı (\"olmak ya da olmamak\").","e2":"To deliver a soliloquy.","e2t":"Kendi kendine (sahne başında) konuşmak."},{"w":"solitude","tr":"yalnızlık / ıssızlık (huzurlu anlamda)","te":"Noun","tt":"İsim","de":"The state of being alone, especially when this is peaceful","dt":"Özellikle huzurlu olan yalnızlık durumu","e1":"He enjoyed the solitude of the mountains.","e1t":"Dağların sessizliğinin (yalnızlığının) tadını çıkardı.","e2":"To live in solitude.","e2t":"İnzivada (yalnız) yaşamak."},{"w":"solstice","tr":"gün dönümü","te":"Noun","tt":"İsim","de":"Either of the two times in the year when the sun is at its highest or lowest point","dt":"Güneşin en yüksek veya en düşük olduğu iki zaman (yaz/kış gün dönümü)","e1":"The summer solstice.","e1t":"Yaz gün dönümü (21 Haziran).","e2":"The winter solstice.","e2t":"Kış gün dönümü (21 Aralık)."},{"w":"somber / sombre","tr":"kasvetli / hüzünlü / koyu renkli","te":"Adjective","tt":"Sıfat","de":"Serious, sad, and without humor; or dark in color","dt":"Ciddi, üzgün ve mizahsız; veya koyu renkli","e1":"A somber expression.","e1t":"Hüzünlü (ciddi) bir ifade.","e2":"To be in a somber mood.","e2t":"Kasvetli bir ruh hali içinde olmak."},{"w":"somnambulist","tr":"uyur gezer","te":"Noun","tt":"İsim","de":"A person who walks while they are asleep","dt":"Uyurken yürüyen kişi","e1":"He has been a somnambulist since childhood.","e1t":"Çocukluğundan beri uyur gezerdir.","e2":"Somnambulism (noun).","e2t":"Uyur gezerlik."},{"w":"somnolent","tr":"uykulu / mahmur / uyku getiren","te":"Adjective","tt":"Sıfat","de":"Feeling as if you want to sleep; or causing sleep","dt":"Uyuma isteği duyan; veya uyku getiren","e1":"A somnolent afternoon.","e1t":"Uyku getiren (rehavet dolu) bir öğleden sonra.","e2":"The somnolent effect of the medicine.","e2t":"İlacın uyku getirici etkisi."},{"w":"sonorous","tr":"tınlayan / gür / dolgun (ses)","te":"Adjective","tt":"Sıfat","de":"(Of a sound) deep, pleasant, and full","dt":"(Ses için) derin, hoş ve dolgun","e1":"A sonorous voice.","e1t":"Gür ve dolgun bir ses.","e2":"The sonorous church bells.","e2t":"Çınlayan kilise çanları."},{"w":"sophist","tr":"sofist / yanıltıcı mantık yürüten kişi","te":"Noun","tt":"İsim","de":"A person who uses clever but false arguments","dt":"Zekice ama yanlış (yanıltıcı) argümanlar kullanan kişi","e1":"He was a master sophist.","e1t":"O usta bir sofistti.","e2":"Sophistry (noun).","e2t":"Safsata / Yanıltıcı mantık."},{"w":"sophistry","tr":"safsata / yanıltıcı mantık / kelime oyunu","te":"Noun","tt":"İsim","de":"The use of clever but false arguments, especially with the intention of deceiving","dt":"Özellikle aldatma amacıyla kullanılan zekice ama yanlış argümanlar","e1":"His argument was a piece of pure sophistry.","e1t":"Onun iddiası tam bir safsataydı.","e2":"Political sophistry.","e2t":"Siyasi kelime oyunları."},{"w":"soporific","tr":"uyku getirici / uyuşturucu / sıkıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Causing sleep or making a person want to sleep","dt":"Uykuyu getiren veya uyuma isteği uyandıran","e1":"The soporific effect of a heavy meal.","e1t":"Ağır bir yemeğin uyku getirici etkisi.","e2":"A soporific speech.","e2t":"Sıkıcı (uyku getiren) bir konuşma."},{"w":"sordid","tr":"kirli / pespaye / aşağılık / iğrenç","te":"Adjective","tt":"Sıfat","de":"Dirty and unpleasant; or morally wrong and shocking","dt":"Kirli ve nahoş; veya ahlaken yanlış ve şoke edici","e1":"A sordid little room.","e1t":"Kirli, pespaye küçük bir oda.","e2":"The sordid details of the scandal.","e2t":"Skandalın iğrenç detayları."},{"w":"spangle","tr":"pul (süs) / parlamak / pullarla süslemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small piece of shiny metal or plastic used to decorate clothes","dt":"Giysileri süslemek için kullanılan parlak metal/plastik parça","e1":"A dress covered in gold spangles.","e1t":"Altın pullarla kaplı bir elbise.","e2":"The sky was spangled with stars.","e2t":"Gökyüzü yıldızlarla bezenmişti (parlıyordu)."},{"w":"spasmodic","tr":"kesintili / ara sıra olan / spazmlı","te":"Adjective","tt":"Sıfat","de":"Happening suddenly for short periods of time and not at regular intervals","dt":"Düzenli olmayan aralıklarla, aniden ve kısa süreli gerçekleşen","e1":"Spasmodic movements.","e1t":"Spazm gibi (kesintili) hareketler.","e2":"Spasmodic fighting.","e2t":"Ara sıra alevlenen (düzensiz) çatışmalar."},{"w":"specious","tr":"yanıltıcı / görünüşte doğru / aldatıcı","te":"Adjective","tt":"Sıfat","de":"Seeming to be right or true, but really wrong or false","dt":"Doğruymuş gibi görünen ama aslında yanlış olan","e1":"A specious argument.","e1t":"Yanıltıcı (aldatıcı) bir iddia.","e2":"Specious reasoning.","e2t":"Görünüşte mantıklı ama hatalı akıl yürütme."},{"w":"specter / spectre","tr":"hayalet / korku / hortlak","te":"Noun","tt":"İsim","de":"A ghost; or something that causes fear or worry","dt":"Hayalet; veya korku/endişe veren şey","e1":"The specter of war.","e1t":"Savaş hayaleti (korkusu).","e2":"To be haunted by the specter of poverty.","e2t":"Yoksulluk korkusuyla yaşamak."},{"w":"spectral","tr":"hayalet gibi / tayfsal / spektral","te":"Adjective","tt":"Sıfat","de":"Relating to a ghost; or relating to a spectrum","dt":"Hayaletle ilgili; veya bir spektrum (tayf) ile ilgili","e1":"A spectral figure.","e1t":"Hayalet gibi bir figür.","e2":"Spectral analysis (science).","e2t":"Spektral (tayfsal) analiz."},{"w":"spendthrift","tr":"savurgan / müsrif","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who spends money in an extravagant and irresponsible way","dt":"Parayı sorumsuzca ve aşırı harcayan kişi","e1":"My brother is a real spendthrift.","e1t":"Kardeşim tam bir müsrif.","e2":"Spendthrift habits.","e2t":"Savurgan alışkanlıklar."},{"w":"spherical","tr":"küresel / yuvarlak","te":"Adjective","tt":"Sıfat","de":"Shaped like a sphere","dt":"Küre şeklinde","e1":"A spherical object.","e1t":"Küresel bir nesne.","e2":"The Earth is not a perfect sphere but it is spherical.","e2t":"Dünya tam bir küre değildir ama küreseldir."},{"w":"spontaneity","tr":"doğallık / kendiliğindenlik","te":"Noun","tt":"İsim","de":"The quality of being natural rather than planned","dt":"Planlı olmaktan ziyade doğal olma niteliği","e1":"I love the spontaneity of her performance.","e1t":"Onun performansındaki doğallığı (kendiliğindenliği) seviyorum.","e2":"To act with spontaneity.","e2t":"İçinden geldiği gibi (doğal) davranmak."},{"w":"sporadic","tr":"ara sıra olan / tek tük / düzensiz","te":"Adjective","tt":"Sıfat","de":"Happening sometimes; not regular or continuous","dt":"Bazen olan; düzenli veya sürekli olmayan","e1":"Sporadic violence.","e1t":"Tek tük (ara sıra olan) şiddet olayları.","e2":"Sporadic success.","e2t":"Düzensiz başarı."},{"w":"sportive","tr":"oyuncu / şakacı / neşeli","te":"Adjective","tt":"Sıfat","de":"Playful and happy","dt":"Oyuncu ve neşeli","e1":"A sportive child.","e1t":"Oyuncu (neşeli) bir çocuk.","e2":"In a sportive mood.","e2t":"Şakacı bir ruh hali içinde."},{"w":"spry","tr":"dinç / hareketli / çevik (özellikle yaşlılar için)","te":"Adjective","tt":"Sıfat","de":"(Especially of an old person) active and lively","dt":"(Özellikle yaşlılar için) aktif ve hayat dolu","e1":"He's 80 but still very spry.","e1t":"80 yaşında ama hala çok dinç.","e2":"A spry old lady.","e2t":"Çevik yaşlı bir kadın."},{"w":"spurious","tr":"sahte / düzmece / asılsız","te":"Adjective","tt":"Sıfat","de":"False and not what it appears to be; or not based on facts","dt":"Sahte ve göründüğü gibi olmayan; veya gerçeklere dayanmayan","e1":"Spurious coins.","e1t":"Sahte paralar.","e2":"Spurious arguments.","e2t":"Asılsız (düzmece) iddialar."},{"w":"spurn","tr":"reddetmek / geri çevirmek / küçümsemek","te":"Verb","tt":"Fiil","de":"To refuse to accept something or someone because you think they are not good enough","dt":"Yeterince iyi olmadığını düşündüğü için birini/bir şeyi reddetmek","e1":"She spurned his offer of marriage.","e1t":"Onun evlilik teklifini geri çevirdi.","e2":"To spurn a chance.","e2t":"Bir şansı tepmek (reddetmek)."},{"w":"squalid","tr":"pis / sefil / kirli / iğrenç","te":"Adjective","tt":"Sıfat","de":"(Of a place) extremely dirty and unpleasant","dt":"(Yer için) son derece kirli ve nahoş","e1":"Squalid living conditions.","e1t":"Sefil (pis) yaşam koşulları.","e2":"A squalid prison cell.","e2t":"Pis bir hapishane hücresi."},{"w":"staccato","tr":"kesik kesik / kısa ve sert (ses)","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"With each sound or note separate from the next","dt":"Her sesin veya notanın bir sonrakinden ayrı olduğu (kesik)","e1":"The staccato sound of a typewriter.","e1t":"Daktilonun kesik kesik sesi.","e2":"He spoke in staccato sentences.","e2t":"Kesik kesik cümlelerle konuştu."},{"w":"staid","tr":"ciddi / ağırbaşlı / sıkıcı","te":"Adjective","tt":"Sıfat","de":"Serious, boring, and slightly old","dt":"fashioned","e1":"Ciddi, sıkıcı ve biraz eski moda","e1t":"A staid office environment.","e2":"Ciddi (sıkıcı) bir ofis ortamı.","e2t":"He has a staid personality."},{"w":"stalemate","tr":"çıkmaz / kilitlenme / pat (satranç)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A situation in which neither group can win or make progress","dt":"Hiçbir grubun kazanamadığı veya ilerleyemediği durum","e1":"The negotiations reached a stalemate.","e1t":"Müzakereler çıkmaza girdi (kilitlendi).","e2":"To break the stalemate.","e2t":"Çıkmazı aşmak."},{"w":"stalwart","tr":"sadık / güçlü / sarsılmaz destekçi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Loyal, especially for a long time; or physically strong","dt":"Özellikle uzun süredir sadık olan; veya fiziksel olarak güçlü","e1":"A stalwart supporter of the party.","e1t":"Partinin sarsılmaz (sadık) bir destekçisi.","e2":"He is a stalwart friend.","e2t":"O sadık bir dosttur."},{"w":"stamina","tr":"dayanıklılık / direnç / güç","te":"Noun","tt":"İsim","de":"The physical or mental energy to do something for a long time","dt":"Bir şeyi uzun süre yapabilmek için gereken fiziksel veya zihinsel enerji","e1":"To build up your stamina.","e1t":"Dayanıklılığını artırmak.","e2":"The race is a test of stamina.","e2t":"Yarış bir dayanıklılık testidir."},{"w":"stanch / staunch","tr":"durdurmak (kan vb.) / kesmek","te":"Verb","tt":"Fiil","de":"To stop something from flowing, especially blood","dt":"Bir şeyin akışını (özellikle kanı) durdurmak","e1":"He used a cloth to stanch the bleeding.","e1t":"Kanamayı durdurmak için bir bez kullandı.","e2":"To stanch the flow of information.","e2t":"Bilgi akışını kesmek."},{"w":"stanza","tr":"kıta / dörtlük","te":"Noun","tt":"İsim","de":"A group of lines in a poem","dt":"Şiirdeki dizeler grubu (kıta)","e1":"The first stanza of the poem.","e1t":"Şiirin ilk kıtası.","e2":"A four","e2t":"line stanza."},{"w":"stentorian","tr":"gür (ses) / çok yüksek sesli","te":"Adjective","tt":"Sıfat","de":"(Of a voice) extremely loud and powerful","dt":"(Ses için) son derece yüksek ve güçlü","e1":"He spoke in stentorian tones.","e1t":"Gür bir sesle konuştu.","e2":"A stentorian command.","e2t":"Çok yüksek sesli bir emir."},{"w":"stigma","tr":"leke / utanç belirtisi / damga","te":"Noun","tt":"İsim","de":"A feeling of disapproval that people have about a particular illness or behavior","dt":"Belirli bir hastalık veya davranışa karşı duyulan toplumsal onaylamama (utanç)","e1":"The social stigma attached to mental illness.","e1t":"Ruhsal hastalıklara yapıştırılan toplumsal damga (leke).","e2":"To remove the stigma.","e2t":"Lekeyi (damgayı) temizlemek."},{"w":"stigmatize / stigmatise","tr":"damgalamak / lekelemek / kötü ad takmak","te":"Verb","tt":"Fiil","de":"To treat someone or something unfairly by disapproving of them","dt":"Birini veya bir şeyi onaylamayarak ona haksız yere kötü bir isim/leke yapıştırmak","e1":"People with HIV were often stigmatized.","e1t":"HIV'li bireyler sık sık toplumca damgalandı (dışlandı).","e2":"To stigmatize poverty.","e2t":"Yoksulluğu bir utanç kaynağı gibi göstermek."},{"w":"stilted","tr":"yapmacık / kasıntı / doğal olmayan (konuşma/yazı)","te":"Adjective","tt":"Sıfat","de":"(Of a way of speaking or writing) too formal and not natural","dt":"(Konuşma veya yazı için) aşırı resmi ve doğal olmayan","e1":"A stilted conversation.","e1t":"Kasıntı (yapmacık) bir konuşma.","e2":"His writing style is rather stilted.","e2t":"Yazı tarzı oldukça yapmacıktır."},{"w":"stint","tr":"kısıntı yapmak / görev süresi / sınırlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"To limit the amount of something; or a fixed period of work","dt":"Bir şeyin miktarını sınırlamak; veya belirlenmiş çalışma süresi","e1":"Don't stint on the food!","e1t":"Yemekten kısmayın!","e2":"A two","e2t":"year stint in the army."},{"w":"stipend","tr":"maaş / burs / düzenli ödeme","te":"Noun","tt":"İsim","de":"A fixed, regular sum of money paid to someone, especially a student or priest","dt":"Özellikle bir öğrenciye veya din adamına ödenen sabit, düzenli ücret","e1":"A monthly stipend for living expenses.","e1t":"Yaşam masrafları için aylık burs (ödeme).","e2":"To receive a small stipend.","e2t":"Küçük bir maaş/ücret almak."},{"w":"stoic","tr":"metanetli / dayanıklı / acıya katlanan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Determined not to complain or show feelings, especially in pain","dt":"Özellikle acı çekerken şikayet etmemeye veya duygularını belli etmemeye kararlı","e1":"He showed a stoic endurance.","e1t":"Metanetli bir dayanıklılık sergiledi.","e2":"To remain stoic in the face of adversity.","e2t":"Zorluklar karşısında sarsılmaz (sakin) kalmak."},{"w":"stolid","tr":"duygusuz / uyuşuk / sakin (tepkisiz)","te":"Adjective","tt":"Sıfat","de":"Showing little or no emotion or imagination; not easily excited","dt":"Az duygu veya hayal gücü gösteren; kolay heyecanlanmayan","e1":"A stolid, expressionless face.","e1t":"Duygusuz, ifadesiz bir yüz.","e2":"He is a stolid man who rarely smiles.","e2t":"Nadiren gülümseyen, ağırkanlı (tepkisiz) bir adamdır."},{"w":"stratagem","tr":"hile / oyun / taktik / savaş hilesi","te":"Noun","tt":"İsim","de":"A plan or trick to deceive an enemy or to get an advantage","dt":"Bir düşmanı aldatmak veya avantaj sağlamak için yapılan plan/hile","e1":"A clever political stratagem.","e1t":"Zekice bir siyasi taktik (oyun).","e2":"To use a stratagem to win.","e2t":"Kazanmak için bir hileye başvurmak."},{"w":"stratify","tr":"katmanlara ayırmak / tabakalaşmak","te":"Verb","tt":"Fiil","de":"To arrange or separate something into different layers or social groups","dt":"Bir şeyi farklı katmanlara veya sosyal gruplara ayırmak","e1":"A highly stratified society.","e1t":"Keskin tabakalara (sınıflara) ayrılmış bir toplum.","e2":"Stratified rocks.","e2t":"Katmanlı kayalar."},{"w":"stratum","tr":"katman / tabaka / sınıf","te":"Noun","tt":"İsim","de":"A layer of rock or earth; or a social class","dt":"Kaya veya toprak tabakası; veya sosyal sınıf","e1":"Different strata of society.","e1t":"Toplumun farklı katmanları (kesimleri).","e2":"A deep stratum of rock.","e2t":"Derin bir kaya tabakası. (Çoğulu: Strata)."},{"w":"strew","tr":"serpmek / yaymak / dağıtmak","te":"Verb","tt":"Fiil","de":"To scatter things over a surface","dt":"Şeyleri bir yüzeyin üzerine yaymak/serpmek","e1":"Flowers were strewn along the path.","e1t":"Yol boyunca çiçekler serpilmişti.","e2":"The room was strewn with books.","e2t":"Oda kitaplarla doluydu (kitaplar her yana dağılmıştı)."},{"w":"striated","tr":"çizgili / yivli","te":"Adjective","tt":"Sıfat","de":"Having long, thin lines, marks, or strips of color","dt":"Üzerinde uzun, ince çizgiler veya renk şeritleri olan","e1":"Striated muscle tissue.","e1t":"Çizgili kas dokusu.","e2":"Striated rocks.","e2t":"Çizgili (yivli) kayalar."},{"w":"stricture","tr":"kısıtlama / eleştiri / daralma (tıp)","te":"Noun","tt":"İsim","de":"A rule that limits what you can do; or severe criticism","dt":"Yapabileceklerinizi sınırlayan kural; veya sert eleştiri","e1":"Strictures on international trade.","e1t":"Uluslararası ticaret üzerindeki kısıtlamalar.","e2":"To face strictures from the press.","e2t":"Basından sert eleştiriler almak."},{"w":"strident","tr":"sert / kulak tırmalayıcı / kavgacı (görüş)","te":"Adjective","tt":"Sıfat","de":"(Of a sound) loud and unpleasant; or expressing opinions in a forceful way","dt":"(Ses için) yüksek ve nahoş; veya görüşleri sert/kavgacı bir şekilde ifade eden","e1":"A strident voice.","e1t":"Kulak tırmalayıcı (sert) bir ses.","e2":"Strident criticism.","e2t":"Sert (saldırgan) eleştiri."},{"w":"strut","tr":"kasılarak yürümek / çalım satmak / destek (teknik)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk in a proud way; or a bar used to support a structure","dt":"Gururlu (kasılarak) bir şekilde yürümek; veya bir yapıyı destekleyen çubuk","e1":"He strutted around like a peacock.","e1t":"Tavus kuşu gibi kasılarak (çalım satarak) etrafta dolaştı.","e2":"An aircraft wing strut.","e2t":"Uçak kanat desteği (dikmesi)."},{"w":"stultify","tr":"köreltmek / anlamsız kılmak / budalalaştırmak","te":"Verb","tt":"Fiil","de":"To make someone or something seem stupid or useless","dt":"Birini veya bir şeyi aptalca veya yararsız göstermek (etkisini yitirtmek)","e1":"A stultifying routine.","e1t":"İnsanı körelten (budalalaştıran) rutin.","e2":"The heat stultified our efforts.","e2t":"Sıcak çabalarımızı anlamsız kıldı (bizi uyuşturdu)."},{"w":"stupefy","tr":"sersemletmek / hayretler içinde bırakmak","te":"Verb","tt":"Fiil","de":"To make someone unable to think or feel clearly","dt":"Birinin net düşünmesini veya hissetmesini engellemek (sersemletmek)","e1":"Stupefied by drink.","e1t":"İçkiden sersemlemiş.","e2":"I was stupefied by the news.","e2t":"Haber karşısında şaşkınlıktan donakaldım."},{"w":"stupor","tr":"sersemlik / kendinden geçme / uyuşukluk","te":"Noun","tt":"İsim","de":"A state in which a person is almost unconscious and cannot think clearly","dt":"Birinin neredeyse bilincini yitirdiği ve net düşünemediği durum","e1":"He was in a drunken stupor.","e1t":"Sarhoşluktan kendinden geçmiş (sersemlemiş) haldeydi.","e2":"To fall into a stupor.","e2t":"Uyuşukluğa (sersemliğe) dalmak."},{"w":"suavity","tr":"naziklik / zarafet / tatlı dillilik","te":"Noun","tt":"İsim","de":"The quality of being polite, pleasant, and confident","dt":"Nazik, hoş ve kendinden emin olma niteliği","e1":"He was known for his urbanity and suavity.","e1t":"Kibarlığı ve zarafetiyle bilinirdi.","e2":"Suave (adjective).","e2t":"Nazik / Görgülü."},{"w":"subjection","tr":"boyun eğdirme / bağımlılık / tebaalık","te":"Noun","tt":"İsim","de":"The act of bringing a person or country under one's control","dt":"Bir kişiyi veya ülkeyi kontrolü altına alma eylemi","e1":"The subjection of women.","e1t":"Kadınların boyun eğdirilmesi (ikincil konumu).","e2":"To live in subjection.","e2t":"Bağımlı (boyun eğmiş) halde yaşamak."},{"w":"subjugate","tr":"boyun eğdirmek / fethetmek / köleleştirmek","te":"Verb","tt":"Fiil","de":"To defeat and control a person or country (formal)","dt":"Bir kişiyi veya ülkeyi yenip kontrol altına almak (resmi)","e1":"To subjugate a nation.","e1t":"Bir milleti boyun eğdirmek (esaret altına almak).","e2":"To subjugate one's own desires.","e2t":"Kendi arzularına hakim olmak."},{"w":"subliminal","tr":"bilinçaltı / eşik altı","te":"Adjective","tt":"Sıfat","de":"Affecting your mind without you knowing it","dt":"Farkında olmadan zihninizi etkileyen","e1":"Subliminal advertising.","e1t":"Bilinçaltı reklamcılık.","e2":"A subliminal message.","e2t":"Bilinçaltı (eşik altı) mesaj."},{"w":"submissive","tr":"boyun eğen / uysal / itaatkar","te":"Adjective","tt":"Sıfat","de":"Allowing yourself to be controlled by other people","dt":"Kendini başkalarının kontrolüne bırakan","e1":"A submissive wife.","e1t":"İtaatkar (uysal) bir eş.","e2":"To be submissive to authority.","e2t":"Otoriteye boyun eğmek."},{"w":"suborn","tr":"rüşvetle kandırmak / yalan yere şahitliğe zorlamak","te":"Verb","tt":"Fiil","de":"To persuade someone to act illegally or give false evidence","dt":"Birini yasadışı davranmaya veya yalan şahitlik yapmaya ikna etmek","e1":"To suborn a witness.","e1t":"Bir tanığa rüşvet vererek (veya zorlayarak) yalan söyletmek.","e2":"","e2t":""},{"w":"subpoena","tr":"mahkemeye çağırmak / mahkeme çağrısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official document ordering someone to appear in court","dt":"Birinin mahkemeye gelmesini emreden resmi belge","e1":"To be served with a subpoena.","e1t":"Kendisine mahkeme çağrısı tebliğ edilmek.","e2":"They subpoenaed him to testify.","e2t":"İfade vermesi için onu mahkemeye çağırdılar."},{"w":"subservient","tr":"kölece / dalkavukça / ikincil / hizmet eden","te":"Adjective","tt":"Sıfat","de":"Too willing to obey other people; or less important","dt":"Başkalarına itaat etmeye çok meraklı; veya daha az önemli","e1":"A subservient attitude.","e1t":"Kölece (yaltakçı) bir tavır.","e2":"Women were expected to be subservient to men.","e2t":"Kadınların erkeklere hizmet etmesi (itaat etmesi) beklenirdi."},{"w":"subsistence","tr":"geçim / yaşamını sürdürme / mevcudiyet","te":"Noun","tt":"İsim","de":"The state of having just enough food or money to stay alive","dt":"Hayatta kalacak kadar yiyecek veya paraya sahip olma durumu","e1":"Subsistence farming.","e1t":"Geçimlik tarım (sadece kendi ihtiyacı için).","e2":"To live at a subsistence level.","e2t":"Asgari geçim düzeyinde yaşamak."},{"w":"substantiate","tr":"kanıtlamak / doğrulamak / somutlaştırmak","te":"Verb","tt":"Fiil","de":"To provide facts or evidence to support a claim","dt":"Bir iddiayı desteklemek için gerçekler veya kanıtlar sunmak","e1":"There is little evidence to substantiate the rumors.","e1t":"Söylentileri doğrulayacak (kanıtlayacak) çok az delil var.","e2":"To substantiate a charge.","e2t":"Bir suçlamayı kanıtlarla desteklemek."},{"w":"substantive","tr":"önemli / gerçek / esaslı / bağımsız","te":"Adjective","tt":"Sıfat","de":"Important, serious, or related to real facts","dt":"Önemli, ciddi veya gerçek gerçeklerle ilgili","e1":"Substantive changes to the law.","e1t":"Yasada yapılan esaslı (önemli) değişiklikler.","e2":"To have substantive discussions.","e2t":"Ciddi (içerikli) görüşmeler yapmak."},{"w":"subsume","tr":"kapsamak / bünyesine katmak / dahil etmek","te":"Verb","tt":"Fiil","de":"To include something as part of a larger group","dt":"Bir şeyi daha büyük bir grubun parçası olarak dahil etmek","e1":"Most of these categories can be subsumed under one heading.","e1t":"Bu kategorilerin çoğu tek bir başlık altında toplanabilir (kapsanabilir).","e2":"To be subsumed into a larger organization.","e2t":"Daha büyük bir organizasyona katılmak (onun parçası olmak)."},{"w":"subterfuge","tr":"hile / oyun / aldatmaca / kaçamak","te":"Noun","tt":"İsim","de":"A trick or a dishonest way of getting what you want","dt":"İstediğini elde etmek için kullanılan hile veya dürüst olmayan yol","e1":"To use subterfuge to gain admission.","e1t":"Giriş izni almak için hileye başvurmak.","e2":"Political subterfuge.","e2t":"Siyasi aldatmaca."},{"w":"succinct","tr":"özlü / kısa ve net","te":"Adjective","tt":"Sıfat","de":"(Of writing/speech) said in a clear and short way","dt":"(Yazı/konuşma için) net ve kısa bir şekilde söylenmiş","e1":"A succinct explanation.","e1t":"Özlü (kısa ve net) bir açıklama.","e2":"Keep your letter succinct.","e2t":"Mektubunu kısa ve öz tut."},{"w":"succor / succour","tr":"yardım / imdat / yardım etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Help given to someone who is suffering (formal)","dt":"Acı çeken birine verilen yardım (resmi)","e1":"To provide succor to the refugees.","e1t":"Mültecilere yardım (imdat) sağlamak.","e2":"To succor the wounded.","e2t":"Yaralılara yardım etmek."},{"w":"suffuse","tr":"kaplamak / bürümek / yayılmak","te":"Verb","tt":"Fiil","de":"To spread through or over something completely","dt":"Bir şeyin içinden veya üzerinden tamamen yayılmak","e1":"Her face was suffused with light.","e1t":"Yüzü ışıkla kaplanmıştı (parlıyordu).","e2":"The room was suffused with a soft pink glow.","e2t":"Oda yumuşak pembe bir parıltıyla bürünmüştü."},{"w":"sully","tr":"lekelemek / kirletmek / bozmak","te":"Verb","tt":"Fiil","de":"To spoil something that is pure or has a good reputation","dt":"Saf olan veya iyi itibarı olan bir şeyi bozmak/lekelemek","e1":"To sully someone's reputation.","e1t":"Birinin itibarını lekelemek.","e2":"The white snow was sullied by soot.","e2t":"Beyaz kar kurumla kirlenmişti."},{"w":"summation","tr":"özet / toplama / sonuç","te":"Noun","tt":"İsim","de":"A short repeat of the main points; or the act of adding","dt":"Ana noktaların kısa bir tekrarı; veya toplama işlemi","e1":"The lawyer's summation.","e1t":"Avukatın son konuşması (özeti/mütalaası).","e2":"A summation of the evidence.","e2t":"Kanıtların bir özeti."},{"w":"sunder","tr":"ayırmak / yarmak / koparmak","te":"Verb","tt":"Fiil","de":"To break into separate parts (literary)","dt":"Ayrı parçalara bölmek/ayırmak (edebi)","e1":"A family sundered by the war.","e1t":"Savaşla parçalanmış (ayrılmış) bir aile.","e2":"To sunder a relationship.","e2t":"Bir ilişkiyi koparmak."},{"w":"superannuated","tr":"emekliye ayrılmış / modası geçmiş / çok yaşlı","te":"Adjective","tt":"Sıfat","de":"Old and no longer useful or able to work","dt":"Artık yararlı olmayan veya çalışamayacak kadar yaşlı (emekli)","e1":"Superannuated computing equipment.","e1t":"Miadı dolmuş (modası geçmiş) bilgisayar ekipmanları.","e2":"A superannuated professor.","e2t":"Emekliye ayrılmış bir profesör."},{"w":"supercilious","tr":"kibirli / tepeden bakan / mağrur","te":"Adjective","tt":"Sıfat","de":"Behaving as if you are better than other people","dt":"Diğerlerinden üstünmüş gibi davranan (kibirli)","e1":"A supercilious smile.","e1t":"Küçümseyici (kibirli) bir gülümseme.","e2":"He spoke in a supercilious tone.","e2t":"Tepeden bakan bir ses tonuyla konuştu."},{"w":"superimpose","tr":"üst üste koymak / çakıştırmak","te":"Verb","tt":"Fiil","de":"To put one image or thing on top of another","dt":"Bir görüntüyü veya nesneyi diğerinin üzerine koymak","e1":"The logo was superimposed on the video.","e1t":"Logo videonun üzerine eklendi (bindirildi).","e2":"One map superimposed on another.","e2t":"Üst üste binmiş iki harita."},{"w":"superintend","tr":"denetlemek / yönetmek / nezaret etmek","te":"Verb","tt":"Fiil","de":"To be in charge of something and make sure it is done correctly","dt":"Bir şeyin başında olmak ve doğru yapıldığından emin olmak","e1":"He superintended the construction of the bridge.","e1t":"Köprü inşaatını denetledi (yönetti).","e2":"Superintendent (noun).","e2t":"Denetçi / Emniyet Müdürü."},{"w":"superlative","tr":"en üstün / muazzam / üstünlük derecesi (dilbilgisi)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Of the highest quality; or the form of an adjective (e.g., best)","dt":"En yüksek kalitede (harika); veya sıfatın en üstünlük derecesi","e1":"A superlative performance.","e1t":"Muazzam (harika) bir performans.","e2":"\"Best\" is the superlative of \"good\".","e2t":"\"Best\", \"good\" sıfatının üstünlük derecesidir."},{"w":"supine","tr":"sırtüstü yatan / uyuşuk / pasif","te":"Adjective","tt":"Sıfat","de":"Lying on your back; or being weak and not acting","dt":"Sırtüstü yatan; veya zayıf ve hareketsiz (pasif) kalan","e1":"He lay supine on the grass.","e1t":"Çimenlerin üzerinde sırtüstü yatıyordu.","e2":"A supine government (failing to act).","e2t":"Etkisiz (pasif) bir hükümet."},{"w":"supplant","tr":"yerini almak / saf dışı edip yerine geçmek","te":"Verb","tt":"Fiil","de":"To replace someone or something, often by force or trickery","dt":"Birinin veya bir şeyin (genellikle hile veya güçle) yerini almak","e1":"Printed books will never be supplanted by e","e1t":"books.","e2":"Basılı kitapların yerini asla e","e2t":"kitaplar almayacak."},{"w":"supple","tr":"esnek / bükülebilir / yumuşak","te":"Adjective","tt":"Sıfat","de":"Able to bend easily; or (of a body) moving easily","dt":"Kolayca bükülebilen; veya (vücut için) kolay hareket eden","e1":"Supple leather.","e1t":"Yumuşak (esnek) deri.","e2":"To keep your joints supple.","e2t":"Eklemlerini esnek tutmak."},{"w":"supplicate","tr":"yalvarmak / yakarmak / istirham etmek","te":"Verb","tt":"Fiil","de":"To ask for something in a very humble and emotional way","dt":"Çok alçakgönüllü ve duygusal bir şekilde bir şey istemek","e1":"To supplicate for mercy.","e1t":"Merhamet için yalvarmak.","e2":"Supplicant (noun).","e2t":"Yalvaran (yakaran) kişi."},{"w":"supposition","tr":"varsayım / sanı / tahmin","te":"Noun","tt":"İsim","de":"Something that you believe is true even though you have no proof","dt":"Kanıt olmasa da doğru olduğuna inanılan şey (varsayım)","e1":"Based on pure supposition.","e1t":"Tamamen varsayıma dayalı.","e2":"It is a matter of supposition.","e2t":"Bu bir tahmin meselesidir."},{"w":"surfeit","tr":"aşırılık / bolluk / fazla miktar","te":"Noun/Verb","tt":"İsim/Fiil","de":"An amount that is too large (formal)","dt":"Gereğinden fazla olan miktar (resmi)","e1":"A surfeit of food and drink.","e1t":"Yeme içme aşırılığı (bolluğu).","e2":"To be surfeited with news.","e2t":"Habere doymuş (fazlasıyla maruz kalmış) olmak."},{"w":"surly","tr":"aksi / suratsız / kaba","te":"Adjective","tt":"Sıfat","de":"Unfriendly and rude","dt":"Dostça olmayan ve kaba","e1":"A surly shop assistant.","e1t":"Aksi bir tezgahtar.","e2":"He gave a surly answer.","e2t":"Suratsızca (kaba) bir cevap verdi."},{"w":"surmise","tr":"tahmin etmek / zannetmek / sanı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To guess something without having much proof","dt":"Kanıt olmadan bir şeyi tahmin etmek (zannetmek)","e1":"I surmised that he had forgotten the meeting.","e1t":"Toplantıyı unuttuğunu zannettim (tahmin ettim).","e2":"Pure surmise.","e2t":"Tamamen tahmin."},{"w":"surreptitious","tr":"gizli / kaçamak / sinsi","te":"Adjective","tt":"Sıfat","de":"Done secretly, without anyone seeing or knowing","dt":"Kimse görmeden veya bilmeden gizlice yapılan","e1":"A surreptitious glance.","e1t":"Kaçamak bir bakış.","e2":"Surreptitious meetings.","e2t":"Gizli kapaklı toplantılar."},{"w":"surrogate","tr":"vekil / yedek / yerine geçen","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person or thing that takes the place of another","dt":"Başkasının yerini alan kişi veya şey","e1":"A surrogate mother.","e1t":"Taşıyıcı anne.","e2":"To use a surrogate.","e2t":"Bir vekil (yedek) kullanmak."},{"w":"suture","tr":"dikiş (cerrahi) / dikmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A stitch used to sew up a cut in the body","dt":"Vücuttaki bir kesiği dikmek için kullanılan dikiş","e1":"The doctor removed the sutures.","e1t":"Doktor dikişleri aldı.","e2":"To suture a wound.","e2t":"Bir yarayı dikmek."},{"w":"svelte","tr":"ince / zarif / şık","te":"Adjective","tt":"Sıfat","de":"(Of a person) thin, attractive, and stylish","dt":"(Kişi için) ince, çekici ve şık","e1":"A svelte figure.","e1t":"Zarif (ince) bir vücut.","e2":"She looked svelte in her black dress.","e2t":"Siyah elbisesi içinde çok zarif görünüyordu."},{"w":"swarthy","tr":"esmer / koyu tenli","te":"Adjective","tt":"Sıfat","de":"Having dark skin","dt":"Koyu tenli","e1":"A swarthy complexion.","e1t":"Esmer bir ten rengi.","e2":"A swarthy young man.","e2t":"Esmer (koyu tenli) genç bir adam."},{"w":"swathe","tr":"sarmak / kuşatmak / şerit / alan","te":"Verb/Noun","tt":"Fiil/İsim","de":"To wrap something around something else; or a long strip","dt":"Bir şeyi başka bir şeyle sarmak; veya uzun şerit (alan)","e1":"The mountains were swathed in clouds.","e1t":"Dağlar bulutlarla sarılmıştı (kuşatılmıştı).","e2":"A swathe of bright colors.","e2t":"Parlak renklerden oluşan bir şerit."},{"w":"sybarite","tr":"zevk düşkünü / sefahat düşkünü","te":"Noun","tt":"İsim","de":"A person who loves luxury and expensive things","dt":"Lüksü ve pahalı şeyleri seven kişi","e1":"He lived like a sybarite.","e1t":"Sefahat düşkünü biri gibi yaşadı.","e2":"Sybaritic (adjective).","e2t":"Zevk ve sefaya dayalı."},{"w":"sycophant","tr":"dalkavuk / yaltakçı","te":"Noun","tt":"İsim","de":"A person who praises powerful people to get an advantage","dt":"Avantaj sağlamak için güçlü insanlara yağ çeken kişi","e1":"He's surrounded by sycophants.","e1t":"Etrafı dalkavuklarla çevrili.","e2":"Sycophantic (adjective).","e2t":"Yaltakçı / Yağcı."},{"w":"symbiosis","tr":"ortak yaşam / simbiyoz","te":"Noun","tt":"İsim","de":"A relationship between two organisms that live together and help each other","dt":"Birlikte yaşayan ve birbirine yardım eden iki canlı arasındaki ilişki","e1":"The symbiosis between the bird and the crocodile.","e1t":"Kuş ile timsah arasındaki ortak yaşam (simbiyoz).","e2":"A perfect symbiosis of art and technology.","e2t":"Sanat ve teknolojinin mükemmel uyumu (birlikteliği)."},{"w":"synoptic","tr":"özet niteliğinde / genel bakış sunan","te":"Adjective","tt":"Sıfat","de":"Giving a general view of a whole subject","dt":"Bir konunun bütününe dair genel bir bakış (özet) sunan","e1":"A synoptic report.","e1t":"Özet rapor.","e2":"Synoptic Gospels (Matthew, Mark, Luke).","e2t":"Sinoptik İnciller (benzer bakış açılı)."},{"w":"tabulate","tr":"tablo haline getirmek / çizelgeye dökmek","te":"Verb","tt":"Fiil","de":"To arrange information in the form of a table","dt":"Bilgileri tablo/çizelge şeklinde düzenlemek","e1":"To tabulate the results of a survey.","e1t":"Bir anketin sonuçlarını tabloya dökmek.","e2":"Tabulated data.","e2t":"Tablolanmış veri."},{"w":"tacit","tr":"üstü kapalı / zımni / söylenmemiş ama anlaşılan","te":"Adjective","tt":"Sıfat","de":"Understood or agreed without being stated directly","dt":"Doğrudan söylenmeden anlaşılan veya kabul edilen","e1":"A tacit agreement.","e1t":"Zımni (üstü kapalı) bir anlaşma.","e2":"Tacit approval.","e2t":"Sessiz onay."},{"w":"taciturn","tr":"sessiz / az konuşan / suskun","te":"Adjective","tt":"Sıfat","de":"Tending not to speak much","dt":"Pek konuşmama eğiliminde olan","e1":"A taciturn and lonely man.","e1t":"Sessiz ve yalnız bir adam.","e2":"He was naturally taciturn.","e2t":"Doğası gereği suskundu."},{"w":"tactile","tr":"dokunsal / dokunma duyusuyla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the sense of touch","dt":"Dokunma duyusuyla ilgili","e1":"Tactile feedback.","e1t":"Dokunsal geri bildirim.","e2":"A tactile experience.","e2t":"Dokunsal (dokunarak hissedilen) bir deneyim."},{"w":"talisman","tr":"tılsım / muska / uğur","te":"Noun","tt":"İsim","de":"An object believed to have magic powers or bring good luck","dt":"Sihirli güçleri olduğuna veya uğur getirdiğine inanılan nesne","e1":"He carried the stone as a talisman.","e1t":"Taşı bir tılsım (uğur) olarak taşıdı.","e2":"A protective talisman.","e2t":"Koruyucu tılsım."},{"w":"tangential","tr":"teğetsel / konu dışı / ikincil","te":"Adjective","tt":"Sıfat","de":"Only slightly related to a subject; or touching at one point","dt":"Bir konuyla sadece yüzeysel olarak ilgili; veya (matematik) teğet olan","e1":"Tangential remarks.","e1t":"Konu dışı (ikincil) yorumlar.","e2":"A tangential connection.","e2t":"Dolaylı (zayıf) bir bağlantı."},{"w":"tanner","tr":"tabakçı / deri işleyen kişi","te":"Noun","tt":"İsim","de":"A person whose job is to make animal skins into leather","dt":"Hayvan derilerini işleyerek kösele/deri yapan kişi","e1":"He worked as a tanner in a small village.","e1t":"Küçük bir köyde tabakçı olarak çalıştı.","e2":"Tannery (the place).","e2t":"Tabakhane."},{"w":"tantalize / tantalise","tr":"umutlandırıp üzmek / canını çektirmek / cezbetmek","te":"Verb","tt":"Fiil","de":"To make someone want something that is out of reach","dt":"Birini ulaşılamayacak bir şeye özendirmek (canını çektirmek)","e1":"The smell of food tantalized the hungry man.","e1t":"Yemek kokusu aç adamın canını çektirdi.","e2":"A tantalizing possibility.","e2t":"Cezbedici bir olasılık."},{"w":"tantamount","tr":"eşdeğer / aynı anlama gelen","te":"Adjective","tt":"Sıfat","de":"Having the same bad effect as something else","dt":"Başka bir şeyle aynı (kötü) etkiye sahip olan","e1":"Her refusal was tantamount to a resignation.","e1t":"Reddetmesi istifa etmekle eşdeğerdi.","e2":"Tantamount to treason.","e2t":"Vatana ihanetle eşanlamlı."},{"w":"tautological","tr":"gereksiz tekrarlı / totolojik","te":"Adjective","tt":"Sıfat","de":"Using different words to say the same thing unnecessarily","dt":"Aynı şeyi gereksiz yere farklı kelimelerle söyleyen","e1":"\"Free gift\" is a tautological expression.","e1t":"\"Bedava hediye\" gereksiz tekrarlı (totolojik) bir ifadedir.","e2":"Tautology (noun).","e2t":"Gereksiz tekrar."},{"w":"tawdry","tr":"zevksiz / cafcaflı / ucuz ve gösterişli","te":"Adjective","tt":"Sıfat","de":"Cheap and looking bad; or morally low","dt":"Ucuz ve kötü görünen; veya ahlaken düşük","e1":"Tawdry jewelry.","e1t":"Zevksiz (cafcaflı) takılar.","e2":"A tawdry affair.","e2t":"Çirkin (pespaye) bir ilişki."},{"w":"tedium","tr":"tekdüzelik / sıkıcılık / bıkkınlık","te":"Noun","tt":"İsim","de":"The state of being boring and continuing for a long time","dt":"Sıkıcı ve uzun süredir devam eden durum","e1":"The tedium of a long flight.","e1t":"Uzun bir uçuşun sıkıcılığı.","e2":"To break the tedium of daily life.","e2t":"Günlük hayatın monotonluğunu kırmak."},{"w":"temerity","tr":"cüret / pervasızlık / küstahlık","te":"Noun","tt":"İsim","de":"Excessive confidence or boldness; audacity","dt":"Aşırı güven veya cesaret; yersiz cüret","e1":"He had the temerity to challenge the boss.","e1t":"Patrona meydan okuma cüretini gösterdi.","e2":"To act with great temerity.","e2t":"Büyük bir pervasızlıkla hareket etmek."},{"w":"tempestuous","tr":"fırtınalı / taşkın / hırçın","te":"Adjective","tt":"Sıfat","de":"Characterized by strong and turbulent or conflicting emotion","dt":"Güçlü, çalkantılı veya çatışan duygularla karakterize edilen","e1":"A tempestuous relationship.","e1t":"Fırtınalı (çalkantılı) bir ilişki.","e2":"Tempestuous weather.","e2t":"Çok fırtınalı hava."},{"w":"tenability","tr":"savunulabilirlik / makullük","te":"Noun","tt":"İsim","de":"The quality of being able to be defended or maintained","dt":"Savunulabilir veya sürdürülebilir olma niteliği","e1":"The tenability of his position was questioned.","e1t":"Konumunun savunulabilirliği sorgulandı.","e2":"Tenable (adjective).","e2t":"Savunulabilir / Mantıklı."},{"w":"tenacious","tr":"inatçı / sıkı sıkıya bağlı / vazgeçmeyen","te":"Adjective","tt":"Sıfat","de":"Holding tightly onto something; or persistent","dt":"Bir şeye sıkıca tutunan; veya azimli/inatçı","e1":"A tenacious memory.","e1t":"Güçlü (asla unutmayan) bir hafıza.","e2":"He is a tenacious negotiator.","e2t":"İnatçı (pazarlıktan vazgeçmeyen) bir müzakerecidir."},{"w":"tenet","tr":"ilke / dogma / inanç","te":"Noun","tt":"İsim","de":"A main principle or belief of a religion or philosophy","dt":"Bir dinin veya felsefenin temel ilkesi veya inancı","e1":"One of the central tenets of Christianity.","e1t":"Hristiyanlığın temel ilkelerinden biri.","e2":"The basic tenets of democracy.","e2t":"Demokrasinin temel taşları (ilkeleri)."},{"w":"tensile","tr":"gerilebilir / gerilme ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to tension; or capable of being drawn out or stretched","dt":"Gerilimle ilgili; veya çekilip uzatılabilen","e1":"Tensile strength.","e1t":"Çekme (gerilme) dayanımı.","e2":"Tensile forces.","e2t":"Gerilme kuvvetleri."},{"w":"tenuous","tr":"zayıf / ince / eğreti / belirsiz","te":"Adjective","tt":"Sıfat","de":"Very weak or slight; or very thin","dt":"Çok zayıf veya hafif; veya çok ince","e1":"A tenuous connection between the two events.","e1t":"İki olay arasındaki zayıf (eğreti) bağlantı.","e2":"Her grip on reality was tenuous.","e2t":"Gerçeklikle bağı zayıftı."},{"w":"tepid","tr":"ılık / isteksiz / cansız","te":"Adjective","tt":"Sıfat","de":"(Of a liquid) slightly warm; or showing little enthusiasm","dt":"(Sıvı için) hafif sıcak; veya az heves gösteren","e1":"Tepid water.","e1t":"Ilık su.","e2":"The play received a tepid response from the critics.","e2t":"Oyun eleştirmenlerden cansız (isteksiz) bir tepki aldı."},{"w":"terminus","tr":"son durak / bitiş noktası","te":"Noun","tt":"İsim","de":"The end of a railway or bus route","dt":"Bir tren veya otobüs hattının sonu","e1":"A railway terminus.","e1t":"Demiryolu son durağı.","e2":"The terminus of the canal.","e2t":"Kanalın bitiş noktası."},{"w":"terse","tr":"kısa ve öz / kestirip atan (sert)","te":"Adjective","tt":"Sıfat","de":"Using few words in a way that may seem rude or unfriendly","dt":"Kaba görünebilecek şekilde az kelime kullanan (kısa ve sert)","e1":"A terse reply.","e1t":"Kısa ve sert (kestirip atan) bir cevap.","e2":"He was terse with the staff.","e2t":"Personele karşı sert ve kısa konuşuyordu."},{"w":"testy","tr":"sinirli / aksi / huysuz","te":"Adjective","tt":"Sıfat","de":"Easily annoyed; irritable","dt":"Kolayca sinirlenen; huysuz","e1":"He is a bit testy today.","e1t":"Bugün biraz sinirli (aksi).","e2":"A testy remark.","e2t":"Huysuzca bir yorum."},{"w":"tether","tr":"bağlamak / kısıtlamak / yular / internet paylaşımı","te":"Verb/Noun","tt":"Fiil/İsim","de":"To tie an animal to a post; or to use a mobile phone as a modem","dt":"Bir hayvanı bir direğe bağlamak; veya telefonu modem olarak kullanmak","e1":"The horse was tethered to a fence.","e1t":"At bir çite bağlanmıştı.","e2":"At the end of one's tether (idiom: out of patience).","e2t":"Sabrı taşmış / dayanacak gücü kalmamış."},{"w":"theocracy","tr":"teokrasi / din devleti","te":"Noun","tt":"İsim","de":"A government by religious leaders","dt":"Dini liderler tarafından yönetilen hükümet","e1":"To live in a theocracy.","e1t":"Bir teokraside yaşamak.","e2":"Theocratic rule.","e2t":"Teokratik yönetim."},{"w":"thespian","tr":"oyuncu / tiyatrocu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An actor (formal or humorous)","dt":"Aktör / Oyuncu (resmi veya şakalı)","e1":"A talented young thespian.","e1t":"Yetenekli genç bir oyuncu.","e2":"Thespian skills.","e2t":"Oyunculuk becerileri."},{"w":"thrall","tr":"köle / esir /","te":"in etkisi altında olmak","tt":"Noun","de":"İsim","dt":"The state of being in someone's power (formal)","e1":"Birinin gücü/etkisi altında olma durumu","e1t":"He was in thrall to his passion.","e2":"Tutkusunun esiri olmuştu.","e2t":"To be in the thrall of a charismatic leader."},{"w":"thwart","tr":"engellemek / boşa çıkarmak / mani olmak","te":"Verb","tt":"Fiil","de":"To prevent someone from doing what they intended to do","dt":"Birinin niyetlendiği şeyi yapmasını engellemek","e1":"To thwart a plan.","e1t":"Bir planı boşa çıkarmak.","e2":"Our efforts were thwarted by the bad weather.","e2t":"Çabalarımız kötü hava nedeniyle engellendi."},{"w":"timorous","tr":"korkak / çekingen / ürkek","te":"Adjective","tt":"Sıfat","de":"Nervous and without much confidence (formal)","dt":"Gergin ve özgüvensiz (resmi)","e1":"A timorous voice.","e1t":"Ürkek bir ses.","e2":"He is too timorous to speak in public.","e2t":"Toplum önünde konuşamayacak kadar çekingendir."},{"w":"tirade","tr":"uzun ve sert eleştiri / nutuk","te":"Noun","tt":"İsim","de":"A long, angry speech of criticism or accusation","dt":"Eleştiri veya suçlama içeren uzun, öfkeli konuşma","e1":"She launched into a tirade against the government.","e1t":"Hükümete karşı sert bir nutuk (eleştiri yağmuru) başlattı.","e2":"An angry tirade.","e2t":"Öfkeli bir söylev."},{"w":"titanic","tr":"devasa / muazzam / titanik","te":"Adjective","tt":"Sıfat","de":"Extremely powerful or large","dt":"Son derece güçlü veya büyük","e1":"A titanic struggle.","e1t":"Muazzam (dev) bir mücadele.","e2":"Titanic strength.","e2t":"Dev gibi (olağanüstü) güç."},{"w":"tithe","tr":"ondalık vergi / zekat benzeri ödeme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tenth part of one's income paid to the church","dt":"Gelirin kiliseye ödenen ondalık kısmı","e1":"To pay a tithe to the church.","e1t":"Kiliseye ondalık vergi ödemek.","e2":"Tithing (noun).","e2t":"Ondalık verme pratiği."},{"w":"titillate","tr":"gıdıklamak / heyecanlandırmak / cezbetmek","te":"Verb","tt":"Fiil","de":"To excite someone, especially in a sexual way","dt":"Birini (özellikle cinsel açıdan) heyecanlandırmak/uyarmak","e1":"To titillate the senses.","e1t":"Duyuları uyarmak.","e2":"Tantalizing stories intended to titillate the readers.","e2t":"Okurları cezbetmeyi amaçlayan heyecan verici hikayeler."},{"w":"title","tr":"unvan / başlık / hak (mülkiyet)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A name of a book or job; or a legal right to own something","dt":"Kitap/iş adı; veya yasal mülkiyet hakkı","e1":"The title of the book.","e1t":"Kitabın adı.","e2":"To have a title to the land.","e2t":"Toprak üzerinde mülkiyet hakkı olmak."},{"w":"titter","tr":"kıkırdamak / gizlice gülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"To laugh in a quiet and nervous way","dt":"Sessiz ve gergin bir şekilde gülmek (kıkırdamak)","e1":"The audience tittered at his mistake.","e1t":"Seyirciler onun hatasına kıkırdadılar.","e2":"A nervous titter.","e2t":"Gergin bir kıkırtı."},{"w":"titular","tr":"unvanı olan / sözde / nominal","te":"Adjective","tt":"Sıfat","de":"Having a title but no real power","dt":"Unvanı olan ama gerçek yetkisi olmayan","e1":"The titular head of the state.","e1t":"Devletin sembolik (yetkisiz) başkanı.","e2":"The titular character of a play (named after the title).","e2t":"Oyunun adını taşıyan başkarakteri."},{"w":"toady","tr":"dalkavuk / yağcı / yaltakçı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who praises powerful people to get an advantage","dt":"Çıkar sağlamak için güçlülere dalkavukluk eden kişi","e1":"He is a complete toady.","e1t":"O tam bir dalkavuktur.","e2":"To toady to the boss.","e2t":"Patrona yağ çekmek (yaltaklanmak)."},{"w":"tome","tr":"kalın kitap / cilt","te":"Noun","tt":"İsim","de":"A large, heavy, and serious book","dt":"Büyük, ağır ve ciddi kitap","e1":"A massive tome on history.","e1t":"Tarih üzerine devasa bir cilt.","e2":"Thick tomes.","e2t":"Kalın kitaplar."},{"w":"tonicity","tr":"gerginlik / tonisite (kas/hücre)","te":"Noun","tt":"İsim","de":"The state of healthy tension in a muscle; or osmotic pressure","dt":"Kaslardaki sağlıklı gerginlik durumu; veya ozmotik basınç","e1":"Muscle tonicity.","e1t":"Kas tonusu (gerginliği).","e2":"The tonicity of the solution.","e2t":"Çözeltinin tonisitesi (yoğunluğu)."},{"w":"tonsure","tr":"(rahip) tepesi traşlı saç / traş etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The practice of shaving the top of the head (of a priest)","dt":"Rahibin başının tepesini traş etme pratiği","e1":"A monk's tonsure.","e1t":"Bir keşişin traşlı başı.","e2":"","e2t":""},{"w":"torpor","tr":"uyuşukluk / hareketsizlik / uyku hali","te":"Noun","tt":"İsim","de":"A state of physical or mental inactivity; lethargy","dt":"Fiziksel veya zihinsel hareketsizlik durumu","e1":"In a state of torpor.","e1t":"Uyuşukluk (miskinlik) içinde.","e2":"To shake off one's torpor.","e2t":"Uyuşukluğu üzerinden atmak."},{"w":"torrid","tr":"çok sıcak / yakıcı / tutkulu","te":"Adjective","tt":"Sıfat","de":"Extremely hot and dry; or showing strong feelings","dt":"Son derece sıcak ve kuru; veya güçlü duygular gösteren","e1":"The torrid heat of the desert.","e1t":"Çölün yakıcı sıcağı.","e2":"A torrid love affair.","e2t":"Ateşli (tutkulu) bir aşk ilişkisi."},{"w":"torsion","tr":"bükülme / burulma","te":"Noun","tt":"İsim","de":"The act of twisting something","dt":"Bir şeyi bükme/burma eylemi","e1":"Torsion bar.","e1t":"Burulma çubuğu (torsiyon).","e2":"The torsion of a rope.","e2t":"Bir ipin bükülmesi."},{"w":"torso","tr":"gövde / vücudun üst kısmı","te":"Noun","tt":"İsim","de":"The human body without the head, arms, and legs","dt":"Baş, kollar ve bacaklar hariç insan vücudu","e1":"A muscular torso.","e1t":"Kaslı bir gövde.","e2":"The statue was just a torso.","e2t":"Heykel sadece bir gövdeden ibaretti."},{"w":"tortuous","tr":"dolambaçlı / karışık / hileli","te":"Adjective","tt":"Sıfat","de":"Having many turns and twists; or complicated","dt":"Çok virajlı (dolambaçlı); veya karmaşık","e1":"A tortuous mountain road.","e1t":"Çok virajlı bir dağ yolu.","e2":"A tortuous legal process.","e2t":"Karmaşık (çetrefilli) bir hukuk süreci."},{"w":"totality","tr":"bütünlük / tamlık / tam tutulma","te":"Noun","tt":"İsim","de":"The whole of something; or the state of a total eclipse","dt":"Bir şeyin tamamı; veya tam tutulma (güneş/ay) durumu","e1":"The totality of the evidence.","e1t":"Kanıtların bütünlüğü (tamamı).","e2":"In the path of totality.","e2t":"Tam tutulma hattında."},{"w":"touchstone","tr":"mihenk taşı / ölçüt / kriter","te":"Noun","tt":"İsim","de":"A standard or criterion by which something is judged","dt":"Bir şeyin yargılandığı standart veya ölçüt","e1":"A touchstone for quality.","e1t":"Kalite için bir mihenk taşı.","e2":"To use history as a touchstone.","e2t":"Tarihi bir ölçüt olarak kullanmak."},{"w":"unwieldy","tr":"hantal / taşınması güç","te":"Adjective","tt":"Sıfat","de":"Difficult to move or handle because of its size or weight","dt":"Boyutu veya ağırlığı nedeniyle taşınması veya kontrolü zor","e1":"The piano was very heavy and unwieldy.","e1t":"Piyano çok ağır ve hantaldı.","e2":"Unwieldy bureaucracy.","e2t":"Hantal bürokrasi."},{"w":"vouchsafe","tr":"lütfetmek / bahşetmek","te":"Verb","tt":"Fiil","de":"To give or grant something in a gracious or condescending manner","dt":"Bir şeyi lütuf olarak vermek veya söylemek","e1":"He vouchsafed the information to us.","e1t":"Bilgiyi bize vermeyi lütfetti.","e2":"Vouchsafe an answer.","e2t":"Bir cevap vermeye tenezzül etmek."},{"w":"waft","tr":"esintiyle gelmek / sürüklenmek (koku/ses)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To pass gently through the air","dt":"Havada yavaşça süzülmek veya taşınmak","e1":"The smell of fresh coffee wafted through the room.","e1t":"Taze kahve kokusu odada yayıldı.","e2":"A waft of perfume.","e2t":"Hafif bir parfüm esintisi."},{"w":"wanton","tr":"ahlaksız / sebepsiz / insafsız","te":"Adjective/Noun/Verb","tt":"Deliberate and unprovoked; or sexually unrestrained","de":"Kasti ve sebepsiz; veya ahlaki sınır tanımayan","dt":"The city suffered from wanton destruction.","e1":"Şehir sebepsiz (insafsızca) bir yıkıma uğradı.","e1t":"Wanton violence.","e2":"Durup dururken uygulanan şiddet.","e2t":""},{"w":"yielding","tr":"uysal / esnek / verimli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Inclined to give in; or flexible","dt":"Boyun eğmeye meyilli; veya esnek/verimli","e1":"She has a gentle and yielding nature.","e1t":"Nazik ve uysal bir doğası var.","e2":"High","e2t":"yielding crops."},{"w":"zealot","tr":"fanatik / bağnaz","te":"Noun","tt":"İsim","de":"A person who is fanatical and uncompromising in pursuit of their ideas","dt":"Fikirlerinin peşinde fanatik ve tavizsiz olan kişi","e1":"He is a religious zealot who won't listen to reason.","e1t":"O, mantığı dinlemeyen dini bir bağnazdır.","e2":"Political zealot.","e2t":"Siyasi fanatik."},{"w":"c2","tr":"","te":"","tt":"","de":"","dt":"","e1":"","e1t":"","e2":"","e2t":""},{"w":"abeyance","tr":"askıya alma / ara verme","te":"Noun","tt":"İsim","de":"A state of temporary disuse or suspension","dt":"Geçici olarak kullanılmama veya durdurulma durumu","e1":"The project is in abeyance until we get more funding.","e1t":"Daha fazla kaynak bulana kadar proje askıya alındı.","e2":"Matters held in abeyance.","e2t":"Beklemeye alınan meseleler."},{"w":"abjure","tr":"tövbe etmek / vazgeçmek / (inancını) reddetmek","te":"Verb","tt":"Fiil","de":"To formally reject a belief or a claim","dt":"Bir inancı veya iddiayı resmen reddetmek","e1":"He abjured his allegiance to the king.","e1t":"Krala olan sadakatinden vazgeçti.","e2":"To abjure one's errors.","e2t":"Hatalarından dönmek."},{"w":"abomination","tr":"iğrençlik / nefret edilen şey","te":"Noun","tt":"İsim","de":"Something that causes great dislike or shock","dt":"Büyük nefret veya şoka neden olan şey","e1":"Slavery is an abomination.","e1t":"Kölelik bir iğrençliktir.","e2":"To regard something as an abomination.","e2t":"Bir şeyi nefret verici bulmak."},{"w":"aboriginal","tr":"yerli / en baştan beri var olan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the people who have lived in a country from the earliest times","dt":"Bir ülkede en eski zamanlardan beri yaşayan insanlarla ilgili","e1":"Aboriginal tribes.","e1t":"Yerli kabileler.","e2":"Australian Aboriginal art.","e2t":"Avustralya yerli sanatı."},{"w":"abortive","tr":"başarısız / sonuçsuz / yarıda kalmış","te":"Adjective","tt":"Sıfat","de":"Not successful and finished quickly","dt":"Başarısız olan ve çabuk biten","e1":"An abortive attempt to escape.","e1t":"Başarısız bir kaçış girişimi.","e2":"The project was abortive.","e2t":"Proje sonuçsuz kaldı."},{"w":"abrade","tr":"aşındırmak / sürtünerek kazımak","te":"Verb","tt":"Fiil","de":"To remove part of a surface by rubbing","dt":"Bir yüzeyin bir kısmını sürterek çıkarmak","e1":"The skin was abraded by the fall.","e1t":"Düşme sonucu deri aşındı.","e2":"Harsh cleaners can abrade the surface.","e2t":"Sert temizleyiciler yüzeyi aşındırabilir."},{"w":"abrogate","tr":"yürürlükten kaldırmak / feshetmek (yasa/anlaşma)","te":"Verb","tt":"Fiil","de":"To officially end a law, agreement, or custom","dt":"Bir yasayı, anlaşmayı veya geleneği resmen sona erdirmek","e1":"The treaty was abrogated in 1929.","e1t":"Antlaşma 1929'da feshedildi.","e2":"To abrogate a responsibility.","e2t":"Bir sorumluluğu reddetmek/iptal etmek."},{"w":"abscond","tr":"gizlice kaçmak / (parayla) sıvışmak","te":"Verb","tt":"Fiil","de":"To go away suddenly and secretly in order to escape from somewhere","dt":"Bir yerden kaçmak için aniden ve gizlice uzaklaşmak","e1":"He absconded with the company's funds.","e1t":"Şirketin fonlarıyla (parasıyla) sıvıştı.","e2":"To abscond from prison.","e2t":"Hapishaneden firar etmek."},{"w":"absolution","tr":"günahların affı / aklanma","te":"Noun","tt":"İsim","de":"Official forgiveness for something wrong that someone has done","dt":"Yapılan bir yanlış için verilen resmi affetme","e1":"To grant absolution.","e1t":"Günahlarını bağışlamak.","e2":"She sought absolution from the priest.","e2t":"Rahipten günahlarının affını istedi."},{"w":"abstinence","tr":"sakınma / uzak durma / perhiz (içki/seks)","te":"Noun","tt":"İsim","de":"The act of not doing something you enjoy, especially drinking alcohol","dt":"Özellikle alkol gibi zevk alınan bir şeyi yapmama hali","e1":"Total abstinence from alcohol.","e1t":"Alkolden tamamen uzak durma (içkiyi tamamen bırakma).","e2":"Days of abstinence.","e2t":"Perhiz günleri."},{"w":"abstruse","tr":"anlaşılması güç / karmaşık / derin","te":"Adjective","tt":"Sıfat","de":"Difficult to understand; obscure","dt":"Anlaşılması zor; kapalı","e1":"Abstruse philosophical theories.","e1t":"Anlaşılması güç felsefi teoriler.","e2":"His argument was rather abstruse.","e2t":"İddiası oldukça karmaşıktı."},{"w":"abysmal","tr":"çok kötü / berbat / dipsiz","te":"Adjective","tt":"Sıfat","de":"Extremely bad or of very low quality","dt":"Son derece kötü veya çok düşük kaliteli","e1":"The standard of work was abysmal.","e1t":"İşin kalitesi berbattı.","e2":"An abysmal failure.","e2t":"Korkunç bir başarısızlık."},{"w":"accede","tr":"kabul etmek / razı olmak / (makama) geçmek","te":"Verb","tt":"Fiil","de":"To agree to a request or a proposal","dt":"Bir isteği veya öneriyi kabul etmek","e1":"He finally acceded to their demands.","e1t":"Sonunda onların taleplerini kabul etti.","e2":"To accede to the throne.","e2t":"Tahta çıkmak."},{"w":"accentuate","tr":"vurgulamak / belirginleştirmek","te":"Verb","tt":"Fiil","de":"To emphasize a particular feature of something or to make it more noticeable","dt":"Bir şeyin belirli bir özelliğini vurgulamak veya daha dikkat çekici kılmak","e1":"The dress accentuated her slim figure.","e1t":"Elbise onun ince vücudunu belirginleştirdi.","e2":"To accentuate the positive.","e2t":"Olumlu olana odaklanmak (vurgulamak)."},{"w":"acclivity","tr":"yokuş / yukarı eğim","te":"Noun","tt":"İsim","de":"An upward slope (formal)","dt":"Yukarı doğru eğim, yokuş (resmi)","e1":"A steep acclivity.","e1t":"Dik bir yokuş.","e2":"To climb the acclivity.","e2t":"Yokuşu tırmanmak. (Not: 'Declivity'"},{"w":"accordance","tr":"uyum / uygunluk","te":"Noun","tt":"İsim","de":"Following or obeying a rule or custom","dt":"Bir kurala veya geleneğe uyma","e1":"In accordance with the law.","e1t":"Yasaya uygun olarak.","e2":"To act in accordance with instructions.","e2t":"Talimatlara uygun hareket etmek."},{"w":"accoutre","tr":"donatmak / kuşatmak","te":"Verb","tt":"Fiil","de":"To dress or arm for a specific activity (formal)","dt":"Belirli bir faaliyet için giydirmek veya donatmak","e1":"Soldiers accoutred for battle.","e1t":"Savaşa hazırlanmış (donatılmış) askerler.","e2":"Accoutrements (equipment/clothes).","e2t":"Teçhizat / Aksesuarlar."},{"w":"accretion","tr":"büyüme / birikme / artış","te":"Noun","tt":"İsim","de":"A gradual increase or growth by the addition of new layers","dt":"Yeni katmanların eklenmesiyle kademeli artış veya büyüme","e1":"The accretion of wealth over time.","e1t":"Zamanla servetin birikmesi (artması).","e2":"A geological accretion.","e2t":"Jeolojik birikim."},{"w":"acerbic","tr":"sert / iğneleyici / acı (eleştiri)","te":"Adjective","tt":"Sıfat","de":"Direct and rather cruel, or using sharp criticism","dt":"Doğrudan ve oldukça sert, veya keskin eleştiri içeren","e1":"An acerbic sense of humor.","e1t":"İğneleyici (sert) bir mizah anlayışı.","e2":"Acerbic comments.","e2t":"Sert yorumlar."},{"w":"acquiesce","tr":"sessizce kabul etmek / razı olmak","te":"Verb","tt":"Fiil","de":"To accept or agree to something, often unwillingly","dt":"Genellikle istemeden de olsa bir şeyi kabul etmek veya razı olmak","e1":"She finally acquiesced to their plan.","e1t":"Sonunda onların planına (ses çıkarmadan) razı oldu.","e2":"Acquiescence (noun).","e2t":"Razı olma / Boyun eğme."},{"w":"acrimonious","tr":"sert / şiddetli / kavgacı (tartışma)","te":"Adjective","tt":"Sıfat","de":"Full of anger, arguments, and bad feeling","dt":"Öfke, tartışma ve kötü duygularla dolu","e1":"An acrimonious divorce.","e1t":"Çekişmeli (sert) bir boşanma.","e2":"The meeting ended in an acrimonious dispute.","e2t":"Toplantı sert bir kavgayla bitti."},{"w":"actuarial","tr":"sigorta istatistiği ile ilgili / aktüeryal","te":"Adjective","tt":"Sıfat","de":"Relating to the work of an actuary (calculating insurance risks)","dt":"Sigorta risklerini hesaplayan uzmanların işiyle ilgili","e1":"Actuarial tables.","e1t":"Aktüeryal tablolar (yaşam/risk tabloları).","e2":"Actuarial science.","e2t":"Aktüerya bilimi."},{"w":"adage","tr":"atasözü / vecize / darbımesel","te":"Noun","tt":"İsim","de":"A wise saying that is believed by many people to be true","dt":"Birçok kişi tarafından doğru kabul edilen bilgece söz","e1":"The old adage \"Look before you leap\".","e1t":"\"Dereyi görmeden paçaları sıvama\" atasözü.","e2":"As the adage goes...","e2t":"Atasözünde dendiği gibi..."},{"w":"adduce","tr":"kanıt olarak sunmak / ileri sürmek","te":"Verb","tt":"Fiil","de":"To give as proof or as a reason (formal)","dt":"Kanıt veya neden olarak sunmak (resmi)","e1":"No evidence has been adduced to support the theory.","e1t":"Teoriyi destekleyecek hiçbir kanıt sunulmadı.","e2":"To adduce reasons for a decision.","e2t":"Bir kararın nedenlerini ileri sürmek."},{"w":"adherent","tr":"taraftar / sadık takipçi / yapışık","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who strongly supports a particular person, principle, or set of ideas","dt":"Belirli bir kişiyi, ilkeyi veya fikri güçlü bir şekilde destekleyen kişi","e1":"Adherents to a religion.","e1t":"Bir dinin mensupları (takipçileri).","e2":"An adherent surface.","e2t":"Yapışkan bir yüzey."},{"w":"adjunct","tr":"eklenti / yardımcı / ek parça","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Something added or connected to a larger or more important thing","dt":"Daha büyük veya önemli bir şeye eklenen veya bağlanan şey","e1":"The DVD is a useful adjunct to the textbook.","e1t":"DVD, ders kitabı için yararlı bir eklentidir.","e2":"Adjunct professor.","e2t":"Yarı zamanlı (ek görevli) profesör."},{"w":"adjuration","tr":"yalvarma / yemin ettirme / kesin emir","te":"Noun","tt":"Isim","de":"A solemn appeal or a command (formal)","dt":"Ciddi bir çağrı, yalvarma veya emir (resmi)","e1":"An adjuration to tell the truth.","e1t":"Doğruyu söylemesi için yapılan yeminli çağrı.","e2":"","e2t":""},{"w":"adroit","tr":"becerikli / mahir / kıvrak zekalı","te":"Adjective","tt":"Sıfat","de":"Very skillful and quick in the way you think or move","dt":"Düşünme veya hareket etme tarzında çok becerikli ve hızlı","e1":"An adroit politician.","e1t":"Becerikli (kurnaz) bir siyasetçi.","e2":"She was adroit at avoiding difficult questions.","e2t":"Zor sorulardan kaçınma konusunda mahirdi."},{"w":"adulation","tr":"aşırı övgü / dalkavukluk / tapınma","te":"Noun","tt":"İsim","de":"Very great admiration or praise for someone, especially when it is more than is deserved","dt":"Özellikle hak edilenden fazla olan aşırı hayranlık veya övgü","e1":"The rock star enjoyed the adulation of his fans.","e1t":"Rock yıldızı hayranlarının aşırı ilgisinin (tapınmasının) tadını çıkardı.","e2":"To receive constant adulation.","e2t":"Sürekli el üstünde tutulmak."},{"w":"adulterate","tr":"içine başka madde karıştırarak bozmak / saflığını bozmak","te":"Verb","tt":"Fiil","de":"To make food or drink less pure by adding another substance","dt":"Başka bir madde ekleyerek yiyecek veya içeceğin saflığını bozmak","e1":"Adulterated olive oil.","e1t":"İçine başka yağ karıştırılmış (taklit) zeytinyağı.","e2":"To adulterate the evidence.","e2t":"Kanıtları tahrif etmek (bozmak)."},{"w":"advent","tr":"geliş / varış / zuhur","te":"Noun","tt":"İsim","de":"The arrival of a notable person, thing, or event","dt":"Önemli bir kişinin, şeyin veya olayın gelişi","e1":"The advent of the internet.","e1t":"İnternetin gelişi (ortaya çıkışı).","e2":"With the advent of spring.","e2t":"Baharın gelişiyle."},{"w":"adventitious","tr":"tesadüfi / dışsal / sonradan gelen","te":"Adjective","tt":"Sıfat","de":"Happening by chance rather than as a natural part of something","dt":"Bir şeyin doğal bir parçası olmaktan ziyade şans eseri gerçekleşen","e1":"Adventitious roots (botany).","e1t":"(Gövdeden çıkan) ek kökler.","e2":"Adventitious advantages.","e2t":"Beklenmedik (tesadüfi) avantajlar."},{"w":"adversary","tr":"rakip / hasım / düşman","te":"Noun","tt":"İsim","de":"An enemy or opponent","dt":"Düşman veya rakip","e1":"A political adversary.","e1t":"Siyasi bir rakip.","e2":"He defeated his old adversary.","e2t":"Eski hasmını yendi."},{"w":"adverse","tr":"olumsuz / aksi / zıt","te":"Adjective","tt":"Sıfat","de":"Having a negative or harmful effect on something","dt":"Bir şey üzerinde olumsuz veya zararlı etkisi olan","e1":"Adverse weather conditions.","e1t":"Olumsuz hava koşulları.","e2":"Adverse reactions to a drug.","e2t":"Bir ilaca gösterilen yan (olumsuz) etkiler."},{"w":"advocacy","tr":"savunuculuk / destek / avukatlık","te":"Noun","tt":"İsim","de":"Public support for a particular cause or policy","dt":"Belirli bir dava veya politika için kamuoyu desteği","e1":"Advocacy groups.","e1t":"Hak savunucu gruplar.","e2":"Her advocacy of environmental issues.","e2t":"Çevre sorunlarını savunması."},{"w":"aegis","tr":"himaye / koruma / kalkan","te":"Noun","tt":"İsim","de":"The protection, backing, or support of a particular person or organization","dt":"Belirli bir kişi veya kuruluşun koruması veya desteği","e1":"Under the aegis of the United Nations.","e1t":"Birleşmiş Milletler'in himayesi altında.","e2":"Medical research conducted under the aegis of the university.","e2t":"Üniversitenin çatısı altında yürütülen tıbbi araştırma."},{"w":"aesthetic / esthetic","tr":"estetik / sanatsal / güzel","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to beauty or the appreciation of beauty","dt":"Güzellik veya güzellik algısı ile ilgili","e1":"Aesthetic value.","e1t":"Estetik değer.","e2":"From an aesthetic point of view.","e2t":"Estetik bir açıdan."},{"w":"affected","tr":"yapmacık / etkilenmiş /","te":"den etkilenen","tt":"Adjective","de":"Sıfat","dt":"Not natural or sincere; or influenced by something","e1":"Doğal veya samimi olmayan (yapmacık); veya bir şeyden etkilenmiş","e1t":"An affected accent.","e2":"Yapmacık bir aksan.","e2t":"Affected behavior."},{"w":"affirmation","tr":"onaylama / doğrulama / olumlama","te":"Noun","tt":"İsim","de":"A statement that something is true; or support and encouragement","dt":"Bir şeyin doğru olduğuna dair beyan; veya destek/teşvik","e1":"A positive affirmation.","e1t":"Olumlama (pozitif ifade).","e2":"She nodded in affirmation.","e2t":"Onaylarcasına başını salladı."},{"w":"affliction","tr":"dert / keder / hastalık / bela","te":"Noun","tt":"İsim","de":"Something that causes pain or suffering","dt":"Acı veya ızdırap veren şey","e1":"Blindness can be a terrible affliction.","e1t":"Körlük korkunç bir dert (hastalık) olabilir.","e2":"To help people in their affliction.","e2t":"Dertli günlerinde insanlara yardım etmek."},{"w":"affront","tr":"hakaret etmek / aşağılamak / rencide etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A remark or action that offends someone","dt":"Birini kıran veya aşağılayan söz/eylem","e1":"His message was an affront to my pride.","e1t":"Mesajı gururuma sürülmüş bir lekeydi (hakaretti).","e2":"I was affronted by his lack of respect.","e2t":"Saygısızlığı karşısında rencide oldum."},{"w":"aftermath","tr":"sonrasında gelen dönem / kalıntı / sonuç","te":"Noun","tt":"İsim","de":"The consequences or aftereffects of a significant unpleasant event","dt":"Önemli ve nahoş bir olayın sonuçları veya artçı etkileri","e1":"In the aftermath of the war.","e1t":"Savaşın ardından gelen dönemde.","e2":"The economic aftermath of the pandemic.","e2t":"Pandeminin ekonomik sonuçları."},{"w":"agape","tr":"ağzı açık kalmış / hayretle açılmış","te":"Adjective","tt":"Sıfat","de":"(Of a person's mouth) wide open in surprise or wonder","dt":"(Birinin ağzı için) şaşkınlıktan ardına kadar açılmış","e1":"We watched, mouths agape, as the magician disappeared.","e1t":"Sihirbaz gözden kaybolurken ağzımız açık izledik.","e2":"","e2t":""},{"w":"aggrandize / aggrandise","tr":"büyütmek / yüceltmek / (güç/servet) artırmak","te":"Verb","tt":"Fiil","de":"To make someone or something seem more powerful or important","dt":"Birini veya bir şeyi daha güçlü veya önemli göstermek/yapmak","e1":"He sought to aggrandize himself at the expense of others.","e1t":"Başkalarının sırtından kendini yüceltmeye (zenginleştirmeye) çalıştı.","e2":"Self","e2t":"aggrandizement (noun)."},{"w":"aggregate","tr":"toplam / küme / agrega (beton malzemesi)","te":"Noun/Adjective/Verb","tt":"A whole formed by combining several separate elements","de":"Birkaç ayrı öğenin birleşmesiyle oluşan bütün","dt":"The aggregate score was 4","e1":"3.","e1t":"Toplam skor 4","e2":"3'tü.","e2t":"To aggregate data."},{"w":"aghast","tr":"dehşete düşmüş / dona kalmış","te":"Adjective","tt":"Sıfat","de":"Filled with horror or shock","dt":"Dehşet veya şokla dolmuş","e1":"He was aghast at the sight of the blood.","e1t":"Kanı görünce dehşete düştü.","e2":"To stand aghast.","e2t":"Dona kalmak."},{"w":"agility","tr":"çeviklik / kıvraklık","te":"Noun","tt":"İsim","de":"The ability to move quickly and easily; or think quickly","dt":"Hızlı ve kolay hareket etme; veya hızlı düşünme yeteneği","e1":"Mental agility.","e1t":"Zihin kıvraklığı.","e2":"The agility of a mountain goat.","e2t":"Bir dağ keçisinin çevikliği."},{"w":"agnostic","tr":"agnostik / bilinemezci","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who believes that nothing can be known about the existence of God","dt":"Tanrı'nın varlığı hakkında hiçbir şeyin bilinemeyeceğine inanan kişi","e1":"He is an agnostic.","e1t":"O bir agnostiktir.","e2":"Agnostic views.","e2t":"Bilinemezci görüşler."},{"w":"agrarian","tr":"tarımsal / toprağa dayalı","te":"Adjective","tt":"Sıfat","de":"Relating to cultivated land or the cultivation of land","dt":"Ekili arazi veya arazinin işlenmesi ile ilgili","e1":"An agrarian society.","e1t":"Tarım toplumu.","e2":"Agrarian reform.","e2t":"Toprak reformu."},{"w":"alacrity","tr":"heves / can atma / çeviklik","te":"Noun","tt":"İsim","de":"Brisk and cheerful readiness","dt":"Canlı ve neşeli bir hazır olma durumu","e1":"He accepted the invitation with alacrity.","e1t":"Daveti büyük bir hevesle (hiç ikiletmeden) kabul etti.","e2":"To move with alacrity.","e2t":"Çeviklikle hareket etmek."},{"w":"alchemy","tr":"simya / alşimi","te":"Noun","tt":"İsim","de":"A form of chemistry used in the Middle Ages to turn base metals into gold","dt":"Orta Çağ'da değersiz metalleri altına çevirmek için kullanılan kimya türü","e1":"The secrets of alchemy.","e1t":"Simyanın sırları.","e2":"Political alchemy (transforming something common into something valuable).","e2t":"Siyasi simya."},{"w":"alcove","tr":"niş / girinti / küçük oda","te":"Noun","tt":"İsim","de":"A small space in a room, formed by one part of a wall being further back than the others","dt":"Duvarın bir kısmının geride olmasıyla oluşan oda içi girinti","e1":"A dining alcove.","e1t":"Yemek nişi (girintisi).","e2":"The bed fit neatly into the alcove.","e2t":"Yatak girintiye tam oturdu."},{"w":"alias","tr":"takma ad / lakap / nam","te":"ı diğer","tt":"Noun/Adverb","de":"A false name used especially by a criminal","dt":"Özellikle suçlular tarafından kullanılan sahte ad","e1":"Joseph Smith, alias \"The Fox\".","e1t":"Joseph Smith, nam","e2":"ı diğer \"Tilki\".","e2t":"To live under an alias."},{"w":"alimentary","tr":"beslenme ile ilgili / sindirimle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to food or nourishment","dt":"Gıda veya beslenme ile ilgili","e1":"The alimentary canal.","e1t":"Sindirim kanalı (yolu).","e2":"Alimentary needs.","e2t":"Beslenme ihtiyaçları."},{"w":"alimony","tr":"nafaka","te":"Noun","tt":"İsim","de":"Money that a court orders someone to pay regularly to their former wife or husband","dt":"Mahkemenin eski eşe düzenli ödenmesini emrettiği para","e1":"To pay alimony to his ex","e1t":"wife.","e2":"Eski karısına nafaka ödemek.","e2t":"A dispute over alimony."},{"w":"allay","tr":"yatıştırmak / dindirmek / azaltmak","te":"Verb","tt":"Fiil","de":"To make a negative emotion less strong (formal)","dt":"Olumsuz bir duyguyu hafifletmek (resmi)","e1":"To allay someone's fears.","e1t":"Birinin korkularını dindirmek.","e2":"The government tried to allay public concern.","e2t":"Hükümet halkın endişesini yatıştırmaya çalıştı."},{"w":"allege","tr":"iddia etmek / ileri sürmek (kanıt olmadan)","te":"Verb","tt":"Fiil","de":"To say that someone has done something wrong, but without having any proof","dt":"Kanıt olmadan birinin yanlış bir şey yaptığını söylemek","e1":"He is alleged to have stolen the money.","e1t":"Parayı çaldığı iddia ediliyor.","e2":"Alleged crime.","e2t":"Sözde (iddia edilen) suç."},{"w":"allegory","tr":"alegori / simgesel anlatım","te":"Noun","tt":"İsim","de":"A story or picture that uses symbols to convey a hidden meaning","dt":"Gizli bir anlamı iletmek için semboller kullanan hikaye veya resim","e1":"\"Animal Farm\" is a political allegory.","e1t":"\"Hayvan Çiftliği\" siyasi bir alegoridir.","e2":"Allegorical meaning.","e2t":"Simgesel anlam."},{"w":"alliteration","tr":"aliterasyon / ses yinelemesi","te":"Noun","tt":"İsim","de":"The use of the same letter or sound at the beginning of words close together","dt":"Yakın kelimelerin başında aynı harf veya sesin kullanılması","e1":"\"Peter Piper picked a peck of pickled peppers\" is an example of alliteration.","e1t":"(İngilizce tekerleme) aliterasyon örneğidir.","e2":"","e2t":""},{"w":"alluvion / alluvium","tr":"alüvyon / sel / taşkın","te":"Noun","tt":"İsim","de":"A deposit of clay, silt, sand, and gravel left by flowing water","dt":"Akan suyun bıraktığı kil, mil, kum ve çakıl birikintisi","e1":"Fertile alluvium in the river delta.","e1t":"Nehir deltasındaki verimli alüvyon.","e2":"Alluvial soil.","e2t":"Alüvyonlu toprak."},{"w":"aloof","tr":"soğuk / ilgisiz / mesafeli","te":"Adjective","tt":"Sıfat","de":"Not friendly or willing to take part in things","dt":"Dostça olmayan veya olaylara katılmaya isteksiz","e1":"He remained aloof from the others.","e1t":"Diğerlerine karşı mesafeli (soğuk) kaldı.","e2":"An aloof personality.","e2t":"Mesafeli bir kişilik."},{"w":"amass","tr":"biriktirmek / toplamak / yığmak","te":"Verb","tt":"Fiil","de":"To collect a large amount of something, especially money or information","dt":"Büyük miktarda bir şeyi (özellikle para veya bilgi) toplamak","e1":"He amassed a huge fortune.","e1t":"Devasa bir servet biriktirdi.","e2":"To amass evidence.","e2t":"Kanıt toplamak (yığmak)."},{"w":"amazon","tr":"amazon / savaşçı kadın / dev gibi kadın","te":"Noun","tt":"İsim","de":"A very tall, strong, or powerful woman; or a female warrior","dt":"Çok uzun, güçlü veya nüfuzlu kadın; veya kadın savaşçı","e1":"She was a real amazon of a woman.","e1t":"Gerçek bir amazon (güçlü kadın) gibiydi.","e2":"The Amazons of Greek mythology.","e2t":"Yunan mitolojisindeki Amazonlar."},{"w":"ambidextrous","tr":"iki elini de kullanabilen","te":"Adjective","tt":"Sıfat","de":"Able to use the right and left hands equally well","dt":"Sağ ve sol elini eşit derecede iyi kullanabilen","e1":"An ambidextrous basketball player.","e1t":"İki elini de kullanabilen basketbolcu.","e2":"Ambidexterity (noun).","e2t":"İki ellilik."},{"w":"ambience / ambiance","tr":"hava / atmosfer / ortam","te":"Noun","tt":"İsim","de":"The character and atmosphere of a place","dt":"Bir yerin karakteri ve atmosferi","e1":"The restaurant has a pleasant ambience.","e1t":"Restoranın hoş bir havası var.","e2":"Soft lighting adds to the ambience.","e2t":"Yumuşak ışıklandırma ortama (atmosfere) derinlik katıyor."},{"w":"ambiguous","tr":"belirsiz / iki anlamlı / kapalı","te":"Adjective","tt":"Sıfat","de":"Having or expressing more than one possible meaning","dt":"Birden fazla olası anlamı olan veya ifade eden","e1":"An ambiguous statement.","e1t":"Belirsiz (iki anlama gelebilen) bir ifade.","e2":"His position remains ambiguous.","e2t":"Konumu belirsizliğini koruyor."},{"w":"amble","tr":"yavaşça yürümek / rahvan gitmek / gezinti","te":"Verb/Noun","tt":"Fiil/İsim","de":"To walk in a slow and relaxed way","dt":"Yavaş ve rahat bir şekilde yürümek","e1":"We ambled through the park.","e1t":"Parkta ağır ağır gezindik.","e2":"A pleasant amble.","e2t":"Hoş bir yürüyüş."},{"w":"ambrosia","tr":"tanrıların yiyeceği / çok lezzetli yemek","te":"Noun","tt":"İsim","de":"Something very pleasing to taste or smell; or food of the gods","dt":"Tadı veya kokusu çok hoş olan şey; veya tanrıların yiyeceği","e1":"This chocolate cake is pure ambrosia!","e1t":"Bu çikolatalı kek tam bir ziyafet (tanrıların yiyeceği gibi)!","e2":"","e2t":""},{"w":"ambulatory","tr":"yürüyebilen / gezici / revak (mimari)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to or adapted for walking; or able to walk","dt":"Yürümeyle ilgili; veya yürüyebilen","e1":"Ambulatory patients.","e1t":"Yürüyebilen (yatağa bağımlı olmayan) hastalar.","e2":"An ambulatory corridor in a cathedral.","e2t":"Katedraldeki yürüyüş yolu (revak)."},{"w":"ameliorate","tr":"iyileştirmek / düzeltmek / geliştirmek","te":"Verb","tt":"Fiil","de":"To make a bad or unpleasant situation better (formal)","dt":"Kötü veya nahoş bir durumu daha iyi hale getirmek (resmi)","e1":"Efforts to ameliorate living conditions.","e1t":"Yaşam koşullarını iyileştirme çabaları.","e2":"The situation has been ameliorated.","e2t":"Durum düzeltildi."},{"w":"amenable","tr":"uysal / ikna edilebilir / yatkın","te":"Adjective","tt":"Sıfat","de":"Open and responsive to suggestion; easily persuaded","dt":"Önerilere açık; kolayca ikna edilebilen","e1":"She was amenable to our suggestion.","e1t":"Önerimize açıktı (razı oldu).","e2":"Amenable to treatment.","e2t":"Tedaviye yanıt veren (yatkın)."},{"w":"amenity","tr":"tesis / kolaylık / konfor / nezaket","te":"Noun","tt":"İsim","de":"A desirable or useful feature or facility of a building or place","dt":"Bir binanın veya yerin arzu edilen/yararlı özelliği veya tesisi","e1":"Local amenities like shops and parks.","e1t":"Dükkanlar ve parklar gibi yerel imkanlar (tesisler).","e2":"Social amenities.","e2t":"Sosyal nezaket kuralları."},{"w":"amiss","tr":"ters / yanlış / kusurlu","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not quite right; inappropriate or out of place","dt":"Tam olarak doğru olmayan; uygunsuz veya yersiz","e1":"I felt that something was amiss.","e1t":"Bir şeylerin ters gittiğini hissettim.","e2":"Don't take it amiss (don't be offended).","e2t":"Yanlış anlama (gücenme)."},{"w":"amity","tr":"dostluk / iyi ilişkiler","te":"Noun","tt":"İsim","de":"Friendly relations between people or countries (formal)","dt":"İnsanlar veya ülkeler arasındaki dostane ilişkiler (resmi)","e1":"To live in amity with one's neighbors.","e1t":"Komşularıyla dostluk içinde yaşamak.","e2":"International amity.","e2t":"Uluslararası dostluk."},{"w":"amnesia","tr":"hafıza kaybı / amnezi","te":"Noun","tt":"İsim","de":"A partial or total loss of memory","dt":"Kısmi veya tam hafıza kaybı","e1":"He suffered from temporary amnesia after the accident.","e1t":"Kazadan sonra geçici hafıza kaybı yaşadı.","e2":"Retrograde amnesia.","e2t":"Geriye dönük hafıza kaybı."},{"w":"amnesty","tr":"genel af / af çıkarmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official pardon for people who have been convicted of political offenses","dt":"Siyasi suçlardan hüküm giymiş kişiler için verilen resmi af","e1":"The government granted an amnesty to all political prisoners.","e1t":"Hükümet tüm siyasi mahkumlara genel af ilan etti.","e2":"A tax amnesty.","e2t":"Vergi affı."},{"w":"amoral","tr":"ahlak dışı / ahlakla ilgisi olmayan","te":"Adjective","tt":"Sıfat","de":"Lacking a moral sense; unconcerned with the rightness or wrongness of something","dt":"Ahlaki duygudan yoksun; bir şeyin doğruluğu veya yanlışlığıyla ilgilenmeyen","e1":"Nature is amoral.","e1t":"Doğa ahlak dışıdır (ahlak kavramı barındırmaz).","e2":"An amoral character.","e2t":"Ahlak kaygısı gütmeyen bir karakter. (Not: 'Immoral'"},{"w":"amorphous","tr":"şekilsiz / biçimsiz / belirsiz","te":"Adjective","tt":"Sıfat","de":"Without a clearly defined shape or form","dt":"Belirli bir şekli veya biçimi olmayan","e1":"An amorphous mass of clay.","e1t":"Şekilsiz bir kil kütlesi.","e2":"Amorphous ideas.","e2t":"Belirsiz (oturmamış) fikirler."},{"w":"amphibian","tr":"amfibi / hem karada hem suda yaşayan","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An animal that can live both on land and in water","dt":"Hem karada hem suda yaşayabilen canlı","e1":"Frogs are amphibians.","e1t":"Kurbağalar amfibidir.","e2":"Amphibious vehicle.","e2t":"Amfibik (hem karada hem suda giden) araç."},{"w":"amputate","tr":"(cerrahi müdahale ile) kesmek / ampute etmek","te":"Verb","tt":"Fiil","de":"To cut off a limb by surgical operation","dt":"Bir uzvu cerrahi operasyonla kesmek","e1":"They had to amputate his leg.","e1t":"Bacağını kesmek zorunda kaldılar.","e2":"Amputation (noun).","e2t":"Uzvun kesilmesi."},{"w":"amulet","tr":"muska / tılsım / nazar boncuğu","te":"Noun","tt":"İsim","de":"An ornament thought to give protection against evil","dt":"Kötülüğe karşı koruma sağladığına inanılan süs/nesne","e1":"She wore a gold amulet around her neck.","e1t":"Boynuna altın bir muska takmıştı.","e2":"A protective amulet.","e2t":"Koruyucu tılsım."},{"w":"anachronism","tr":"zaman aşımı / tarih hatası / modası geçmiş şey","te":"Noun","tt":"İsim","de":"Something placed in the wrong historical period","dt":"Yanlış tarihsel döneme yerleştirilmiş şey/hata","e1":"For some, the monarchy is an anachronism.","e1t":"Bazıları için monarşi çağ dışı kalmış bir yapıdır.","e2":"Anachronistic (adjective).","e2t":"Tarihsel olarak tutarsız."},{"w":"analgesic","tr":"ağrı kesici / analjezik","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A drug that relieves pain","dt":"Ağrıyı dindiren ilaç","e1":"Aspirin is a common analgesic.","e1t":"Aspirin yaygın bir ağrı kesicidir.","e2":"Analgesic effect.","e2t":"Ağrı kesici etki."},{"w":"analogous","tr":"benzer / paralel / andıran","te":"Adjective","tt":"Sıfat","de":"Comparable in certain respects","dt":"Belirli açılardan karşılaştırılabilir; benzer","e1":"The wings of a bee are analogous to those of a bird.","e1t":"Arının kanatları kuşunkilerle benzerdir.","e2":"An analogous situation.","e2t":"Benzer bir durum."},{"w":"anarchy","tr":"anarşi / kargaşa / başıbozukluk","te":"Noun","tt":"Isim","de":"A state of disorder due to absence of authority","dt":"Otorite yokluğu nedeniyle oluşan kargaşa durumu","e1":"The country descended into anarchy.","e1t":"Ülke anarşiye sürüklendi.","e2":"Complete anarchy.","e2t":"Tam bir kargaşa."},{"w":"anathema","tr":"aforoz / nefret edilen şey / lanetli","te":"Noun","tt":"İsim","de":"Something that one vehemently dislikes","dt":"Şiddetle nefret edilen şey","e1":"Racial prejudice is an anathema to me.","e1t":"Irkçılık benim için nefret verici (lanetli) bir şeydir.","e2":"To be anathema to someone.","e2t":"Birine iğrenç gelmek."},{"w":"ancillary","tr":"yardımcı / ek / yan (hizmet vb.)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Providing necessary support to the primary activities","dt":"Temel faaliyetlere gerekli desteği sağlayan; yardımcı","e1":"Ancillary services.","e1t":"Yan hizmetler.","e2":"An ancillary role.","e2t":"Yardımcı rol."},{"w":"anecdote","tr":"anekdot / kısa öykü / fıkra","te":"Noun","tt":"İsim","de":"A short amusing or interesting story about a real incident","dt":"Gerçek bir olay hakkında kısa, eğlenceli veya ilginç hikaye","e1":"He told us a funny anecdote about his travels.","e1t":"Seyahatleri hakkında bize komik bir anekdot anlattı.","e2":"Anecdotal evidence.","e2t":"Gözleme/hikayeye dayalı (bilimsel olmayan) kanıt."},{"w":"anesthetic / anaesthetic","tr":"anestezik / uyuşturucu madde","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A substance that induces insensitivity to pain","dt":"Acıya karşı duyarsızlık (uyuşukluk) sağlayan madde","e1":"Under general anesthetic.","e1t":"Genel anestezi altında.","e2":"Local anesthetic.","e2t":"Lokal anestezi."},{"w":"anguish","tr":"keder / ıstırap / acı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Severe mental or physical pain or suffering","dt":"Şiddetli zihinsel veya fiziksel acı","e1":"A cry of anguish.","e1t":"Bir ıstırap çığlığı.","e2":"Mental anguish.","e2t":"Zihinsel keder."},{"w":"angular","tr":"köşeli / açılı / sıska","te":"Adjective","tt":"Sıfat","de":"Having angles or sharp corners; or lean and bony","dt":"Açılı veya keskin köşeli; veya zayıf ve kemikli","e1":"An angular face.","e1t":"Köşeli bir yüz.","e2":"Angular momentum (physics).","e2t":"Açısal momentum."},{"w":"animadversion","tr":"eleştiri / kınama / sitem","te":"Noun","tt":"İsim","de":"A comment or remark expressing criticism (formal)","dt":"Eleştiri ifade eden yorum veya beyan (resmi)","e1":"To pass animadversions on someone's conduct.","e1t":"Birinin davranışını sertçe eleştirmek (kınamak).","e2":"","e2t":""},{"w":"animated","tr":"canlı / hareketli / animasyon","te":"Adjective","tt":"Sıfat","de":"Full of life or excitement; or moving images","dt":"Hayat veya heyecan dolu; veya hareketli görüntüler","e1":"An animated discussion.","e1t":"Canlı (hararetli) bir tartışma.","e2":"Animated film.","e2t":"Animasyon filmi."},{"w":"annals","tr":"yıllıklar / kronikler / tarihsel kayıtlar","te":"Noun","tt":"İsim (Plural)","de":"A record of events year by year","dt":"Yıl bazında olayların kaydı","e1":"In the annals of history.","e1t":"Tarihin yıllıklarında (kayıtlarında).","e2":"Annals of a scientific society.","e2t":"Bilimsel bir topluluğun yıllık yayınları."},{"w":"annotate","tr":"not eklemek / şerh düşmek","te":"Verb","tt":"Fiil","de":"To add notes to a text or diagram giving explanation","dt":"Bir metne veya diyagrama açıklayıcı notlar eklemek","e1":"An annotated edition of Shakespeare.","e1t":"Shakespeare'in notlarla zenginleştirilmiş baskısı.","e2":"To annotate a bibliography.","e2t":"Kaynakçaya notlar eklemek."},{"w":"annuity","tr":"yıllık gelir / taksitli ödeme (sigorta)","te":"Noun","tt":"İsim","de":"A fixed sum of money paid to someone each year","dt":"Birine her yıl ödenen sabit miktar para","e1":"To purchase an annuity.","e1t":"Yıllık gelir (emeklilik sigortası) satın almak.","e2":"A life annuity.","e2t":"Hayat boyu yıllık ödeme."},{"w":"annul","tr":"iptal etmek / geçersiz kılmak / feshetmek","te":"Verb","tt":"Fiil","de":"To declare invalid (an official agreement or marriage)","dt":"Resmi bir anlaşma veya evliliği geçersiz ilan etmek","e1":"The marriage was annulled.","e1t":"Evlilik iptal edildi.","e2":"To annul a contract.","e2t":"Bir sözleşmeyi feshetmek."},{"w":"anodyne","tr":"ağrı kesici / zararsız / etkisiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Not likely to cause offence or disagreement; or a painkiller","dt":"Rahatsızlık veya tartışma yaratması beklenmeyen (zararsız); veya ağrı kesici","e1":"Anodyne music.","e1t":"Dinlendirici (zararsız) müzik.","e2":"His speech was rather anodyne.","e2t":"Konuşması oldukça etkisiz (suya sabuna dokunmayan) idi."},{"w":"anoint","tr":"yağ sürmek / meshetmek / tayin etmek","te":"Verb","tt":"Fiil","de":"To rub with oil as part of a religious ceremony; or to choose","dt":"Dini bir törenin parçası olarak yağlamak; veya (bir makama) seçmek","e1":"To anoint a king.","e1t":"Bir kralı meshetmek (tahta geçirmek).","e2":"He was anointed as the next leader.","e2t":"Gelecek lider olarak seçildi."},{"w":"anomalous","tr":"kuralsız / aykırı / beklenmedik","te":"Adjective","tt":"Sıfat","de":"Deviating from what is standard, normal, or expected","dt":"Standart olandan veya beklenen durumdan sapan; aykırı","e1":"An anomalous result.","e1t":"Beklenmedik (aykırı) bir sonuç.","e2":"Anomalous behavior.","e2t":"Anormal davranış."},{"w":"anonymity","tr":"anonimlik / isimsizlik","te":"Noun","tt":"İsim","de":"The condition of being anonymous","dt":"İsimsiz olma durumu","e1":"To guarantee anonymity.","e1t":"İsimsizliği garanti etmek.","e2":"He requested anonymity.","e2t":"İsminin gizli tutulmasını (anonim kalmayı) istedi."},{"w":"antagonism","tr":"düşmanlık / zıtlık / karşıtlık","te":"Noun","tt":"İsim","de":"Active hostility or opposition","dt":"Aktif düşmanlık veya karşıtlık","e1":"Antagonism between rival gangs.","e1t":"Rakip çeteler arasındaki düşmanlık.","e2":"To arouse antagonism.","e2t":"Karşıtlık uyandırmak."},{"w":"antagonist","tr":"rakip / düşman / karşıt karakter","te":"Noun","tt":"İsim","de":"A person who actively opposes or is hostile to someone","dt":"Birine aktif olarak karşı çıkan veya düşmanlık besleyen kişi","e1":"His chief political antagonist.","e1t":"Onun baş siyasi rakibi.","e2":"(Edebiyatta protagonist'in zıttı).","e2t":""},{"w":"antecede","tr":"","te":"den önce gelmek / önde gelmek","tt":"Verb","de":"Fiil","dt":"To come before in time or order (formal)","e1":"Zaman veya sıra bakımından daha önce gelmek (resmi)","e1t":"The cause must antecede the effect.","e2":"Neden sonuçtan önce gelmelidir.","e2t":"Antecedence (noun)."},{"w":"antecedents","tr":"geçmiş / soy sop / öncüller","te":"Noun","tt":"İsim (Plural)","de":"A person's ancestors or social background; or preceding events","dt":"Bir kişinin ataları veya geçmişi; veya önceki olaylar","e1":"To examine someone's antecedents.","e1t":"Birinin geçmişini (soyunu sopunu) incelemek.","e2":"Historical antecedents.","e2t":"Tarihsel öncüller."},{"w":"antediluvian","tr":"tufan öncesi / çok eski / antika","te":"Adjective","tt":"Sıfat","de":"Belonging to the time before the biblical Flood; or ridiculously old","dt":"fashioned","e1":"Tufan (Nuh Tufanı) öncesine ait; veya gülünç derecede eski moda","e1t":"Antediluvian ideas.","e2":"Çok eski (çağ dışı) fikirler.","e2t":"My grandfather's antediluvian computer."},{"w":"anterior","tr":"ön / önde bulunan","te":"Adjective","tt":"Sıfat","de":"Nearer the front, especially situated in the front of the body","dt":"Ön tarafa yakın; özellikle vücudun ön kısmında bulunan","e1":"The anterior part of the brain.","e1t":"Beynin ön kısmı.","e2":"Anterior cruciate ligament (ACL).","e2t":"Ön çapraz bağ."},{"w":"anthem","tr":"marş / ilahi","te":"Noun","tt":"İsim","de":"A rousing or uplifting song identified with a particular group","dt":"Belirli bir grupla özdeşleşen, heyecan verici şarkı/marş","e1":"The national anthem.","e1t":"Ulusal marş (İstiklal Marşı).","e2":"A rock anthem.","e2t":"Bir rock marşı."},{"w":"anthology","tr":"antoloji / seçki","te":"Noun","tt":"İsim","de":"A published collection of poems or other pieces of writing","dt":"Şiirlerin veya diğer yazıların yayınlanmış bir koleksiyonu","e1":"An anthology of modern poetry.","e1t":"Modern şiir antolojisi.","e2":"Short story anthology.","e2t":"Kısa öykü seçkisi."},{"w":"anthropoid","tr":"insansı / insana benzeyen","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Resembling a human being in form","dt":"Form olarak insana benzeyen","e1":"Anthropoid apes.","e1t":"İnsansı maymunlar (şempanze, goril vb.).","e2":"Anthropoid features.","e2t":"İnsansı özellikler."},{"w":"anthropomorphic","tr":"insan biçimli / kişileştirilmiş","te":"Adjective","tt":"Sıfat","de":"Having human characteristics","dt":"İnsan özelliklerine (kişiliğine) sahip olan","e1":"Anthropomorphic gods.","e1t":"İnsan biçimli (insani duyguları olan) tanrılar.","e2":"Anthropomorphism (noun).","e2t":"İnsanbiçimcilik."},{"w":"anticlimax","tr":"hayal kırıklığı / beklentinin boşa çıkması","te":"Noun","tt":"İsim","de":"A disappointing end to an exciting series of events","dt":"Heyecan verici bir olaylar dizisinin hayal kırıklığıyla biten sonu","e1":"The final chapter of the book was a bit of an anticlimax.","e1t":"Kitabın son bölümü biraz hayal kırıklığıydı.","e2":"To end in an anticlimax.","e2t":"Beklentinin altında bir sonla bitmek."},{"w":"antipathy","tr":"antipati / nefret / güçlü soğukluk","te":"Noun","tt":"İsim","de":"A deep","dt":"seated feeling of aversion or dislike","e1":"Kökleşmiş nefret veya hoşnutsuzluk hissi","e1t":"A personal antipathy between the two leaders.","e2":"İki lider arasındaki kişisel antipati.","e2t":"To feel antipathy towards someone."},{"w":"antiquated","tr":"modası geçmiş / çağ dışı / antika","te":"Adjective","tt":"Sıfat","de":"Old","dt":"fashioned or outdated","e1":"Eski moda veya güncelliğini yitirmiş","e1t":"Antiquated technology.","e2":"Çağ dışı kalmış teknoloji.","e2t":"Antiquated laws."},{"w":"antithesis","tr":"antitez / tam zıtlık / karşıt görüş","te":"Noun","tt":"İsim","de":"A person or thing that is the direct opposite of someone or something else","dt":"Birinin veya bir şeyin tam zıttı olan kişi veya şey","e1":"Slavery is the antithesis of freedom.","e1t":"Kölelik özgürlüğün antitezidir (tam zıttıdır).","e2":"The direct antithesis of his earlier claims.","e2t":"Önceki iddialarının tam tersi."},{"w":"apathy","tr":"ilgisizlik / kayıtsızlık / hissizlik","te":"Noun","tt":"İsim","de":"Lack of interest, enthusiasm, or concern","dt":"İlgi, heves veya endişe eksikliği","e1":"Student apathy is a real problem.","e1t":"Öğrenci kayıtsızlığı gerçek bir sorundur.","e2":"To fall into a state of apathy.","e2t":"Hissizlik (umursamazlık) içine düşmek."},{"w":"ape","tr":"taklit etmek / maymun","te":"Verb/Noun","tt":"Fiil/İsim","de":"To imitate someone or something in an absurd or unthinking way","dt":"Birini veya bir şeyi saçma veya düşüncesizce taklit etmek","e1":"He escaped by aping the guard's accent.","e1t":"Gardiyanın aksanını taklit ederek kaçtı.","e2":"To ape someone's behavior.","e2t":"Birinin davranışını (maymun iştahıyla) taklit etmek."},{"w":"aperture","tr":"açıklık / delik / diyafram","te":"Noun","tt":"İsim","de":"An opening, hole, or gap","dt":"Açıklık, delik veya boşluk","e1":"A small aperture in the wall.","e1t":"Duvardaki küçük bir açıklık.","e2":"Camera aperture.","e2t":"Kamera diyaframı (ışık deliği)."},{"w":"apex","tr":"zirve / tepe noktası / doruk","te":"Noun","tt":"İsim","de":"The top or highest part of something","dt":"Bir şeyin en üst veya en yüksek kısmı","e1":"At the apex of his career.","e1t":"Kariyerinin zirvesinde.","e2":"The apex of a triangle.","e2t":"Bir üçgenin tepe noktası."},{"w":"aphorism","tr":"aforizma / özlü söz / vecize","te":"Noun","tt":"İsim","de":"A pithy observation which contains a general truth","dt":"Genel bir gerçeği içeren kısa ve özlü gözlem","e1":"\"Haste makes waste\" is a well","e1t":"known aphorism.","e2":"\"Acele işe şeytan karışır\" bilinen bir aforizmadır.","e2t":"To speak in aphorisms."},{"w":"apiary","tr":"arılık / arı kovanlığı","te":"Noun","tt":"İsim","de":"A place where bees are kept","dt":"Arıların tutulduğu yer","e1":"He keeps dozens of hives in his apiary.","e1t":"Arılığında onlarca kovan tutuyor.","e2":"Apiculture (beekeeping).","e2t":"Arıcılık."},{"w":"aplomb","tr":"özgüven / soğukkanlılık / sarsılmazlık","te":"Noun","tt":"İsim","de":"Self","dt":"confidence or assurance, especially when in a demanding situation","e1":"Özellikle zor durumlarda sergilenen özgüven veya soğukkanlılık","e1t":"She handled the difficult question with great aplomb.","e2":"Zor soruyu büyük bir soğukkanlılıkla yanıtladı.","e2t":"To act with aplomb."},{"w":"apocalyptic","tr":"kıyametvari / felaket getiren / vahiy ile ilgili","te":"Adjective","tt":"Sıfat","de":"Describing or prophesying the complete destruction of the world","dt":"Dünyanın tamamen yok oluşunu tarif eden veya kehanet eden","e1":"An apocalyptic vision of the future.","e1t":"Geleceğe dair kıyametvari bir vizyon.","e2":"Apocalyptic literature.","e2t":"Kıyamet edebiyatı."},{"w":"apocryphal","tr":"uydurma / şüpheli / doğruluğu tartışmalı","te":"Adjective","tt":"Sıfat","de":"(Of a story) widely circulated as being true, but of doubtful authenticity","dt":"(Hikaye için) doğru olduğu yaygın olarak söylenen ancak kaynağı şüpheli olan","e1":"An apocryphal story about the king.","e1t":"Kral hakkında uydurma (şüpheli) bir hikaye.","e2":"Apocryphal gospels.","e2t":"Apokrif (resmi kabul edilmeyen) inciller."},{"w":"apogee","tr":"en yüksek nokta / zirve / yeröte (astronomi)","te":"Noun","tt":"Isim","de":"The highest point in the development of something; or the point in orbit farthest from earth","dt":"Bir gelişimin en yüksek noktası; veya yörüngede dünyaya en uzak nokta","e1":"The apogee of his influence.","e1t":"Nüfuzunun zirvesi.","e2":"The satellite reached its apogee.","e2t":"Uydu en uzak noktasına (yeröte) ulaştı."},{"w":"apolitical","tr":"siyaset dışı / apolitik","te":"Adjective","tt":"Sıfat","de":"Not interested in or involved in politics","dt":"Siyasetle ilgilenmeyen veya siyasetin dışında kalan","e1":"An apolitical organization.","e1t":"Siyaset dışı bir organizasyon.","e2":"He remained strictly apolitical.","e2t":"Kesinlikle apolitik kaldı."},{"w":"apologist","tr":"savunucu / müdafi (özellikle tartışmalı bir fikir için)","te":"Noun","tt":"İsim","de":"A person who offers an argument in defense of something controversial","dt":"Tartışmalı bir şeyi savunmak için argüman sunan kişi","e1":"An apologist for the regime.","e1t":"Rejim savunucusu.","e2":"To act as an apologist for a particular theory.","e2t":"Belirli bir teorinin müdafiliğini yapmak."},{"w":"apostate","tr":"dinden dönen / inancını terk eden / dönek","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who renounces a religious or political belief or principle","dt":"Dini veya siyasi bir inancı ya da ilkeyi terk eden kişi","e1":"He was branded an apostate.","e1t":"Dininden dönen biri (mürted) olarak damgalandı.","e2":"Apostasy (noun).","e2t":"İnançtan dönme."},{"w":"apothecary","tr":"eczacı (eski terim) / aktar","te":"Noun","tt":"İsim","de":"A person who prepared and sold medicines and drugs (historical)","dt":"İlaç hazırlayan ve satan kişi (tarihi)","e1":"The local apothecary's shop.","e1t":"Yerel eczacı dükkanı.","e2":"Herbal apothecary.","e2t":"Bitkisel ilaçlar satan kişi."},{"w":"apothegm","tr":"vecize / özlü söz / aforizma","te":"Noun","tt":"İsim","de":"A short, pithy, and instructive saying","dt":"Kısa, özlü ve öğretici söz","e1":"A legal apothegm.","e1t":"Hukuki bir vecize.","e2":"(Aphorism ile eşanlamlıdır).","e2t":""},{"w":"apotheosis","tr":"tanrılaştırma / mükemmel örnek / doruk","te":"Noun","tt":"İsim","de":"The highest point in the development of something; or elevation to divine status","dt":"Bir gelişimin en üst noktası; veya tanrısal statüye yükseltme","e1":"The apotheosis of his career.","e1t":"Kariyerinin doruk noktası.","e2":"She was the apotheosis of Hollywood glamour.","e2t":"Hollywood ihtişamının mükemmel bir örneğiydi."},{"w":"appall","tr":"dehşete düşürmek / korkutmak / şoke etmek","te":"Verb","tt":"Fiil","de":"Greatly dismay or horrify","dt":"Büyük ölçüde dehşete düşürmek veya korkutmak","e1":"The conditions in the prison appall me.","e1t":"Hapishanedeki koşullar beni dehşete düşürüyor.","e2":"To be appalled by the news.","e2t":"Haberler karşısında şoke olmak."},{"w":"appellation","tr":"ad / unvan / isim","te":"Noun","tt":"İsim","de":"A name or title","dt":"Ad veya unvan","e1":"\"The King of Pop\" was his common appellation.","e1t":"\"Popun Kralı\" onun yaygın unvanıydı.","e2":"To deserve the appellation.","e2t":"Bu adı (unvanı) hak etmek."},{"w":"append","tr":"eklemek / iliştirmek","te":"Verb","tt":"Fiil","de":"To add something as an attachment or supplement","dt":"Ek veya ilave olarak bir şey eklemek","e1":"To append a signature to a document.","e1t":"Bir belgeye imza eklemek.","e2":"Please append the notes to the report.","e2t":"Lütfen notları rapora iliştirin."},{"w":"apportion","tr":"paylaştırmak / bölüştürmek / tahsis etmek","te":"Verb","tt":"Fiil","de":"To divide and assign in shares","dt":"Paylara bölmek ve atamak","e1":"To apportion the blame.","e1t":"Suçu paylaştırmak (kimin suçlu olduğuna karar vermek).","e2":"The funds were apportioned among the various departments.","e2t":"Fonlar çeşitli departmanlar arasında bölüştürüldü."},{"w":"apposite","tr":"uygun / yerinde / alakalı","te":"Adjective","tt":"Sıfat","de":"Apt in the circumstances or in relation to something","dt":"Mevcut duruma uygun veya bir şeyle alakalı","e1":"An apposite remark.","e1t":"Yerinde (tam isabet) bir yorum.","e2":"To find an apposite example.","e2t":"Uygun bir örnek bulmak."},{"w":"apprentice","tr":"çırak / stajyer","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who is learning a trade from a skilled employer","dt":"Becerikli bir işverenden zanaat öğrenen kişi","e1":"An apprentice plumber.","e1t":"Tesisatçı çırağı.","e2":"He was apprenticed to a carpenter.","e2t":"Bir marangozun yanına çırak olarak verildi."},{"w":"approbation","tr":"onay / takdir / tasvip","te":"Noun","tt":"Isim","de":"Approval or praise (formal)","dt":"Onay veya övgü (resmi)","e1":"The king's smile showed his approbation.","e1t":"Kralın gülümsemesi tasvibini (onayını) gösteriyordu.","e2":"To receive official approbation.","e2t":"Resmi onay almak."},{"w":"appurtenance","tr":"eklenti / aksesuar / aidiyet","te":"Noun","tt":"İsim","de":"An accessory or other item associated with a particular activity or lifestyle","dt":"Belirli bir faaliyet veya yaşam tarzıyla ilişkili aksesuar veya öğe","e1":"The appurtenances of wealth.","e1t":"Zenginliğin getirileri (aksesuarları).","e2":"Every appurtenance of modern life.","e2t":"Modern hayatın her türlü gereci."},{"w":"apropos","tr":"hakkında / ile ilgili olarak / yerinde","te":"Preposition/Adjective","tt":"With reference to; or very appropriate to a particular situation","de":"...ile ilgili olarak; veya belirli bir duruma çok uygun","dt":"Apropos of our discussion...","e1":"Tartışmamızla ilgili olarak...","e1t":"The remark was very apropos.","e2":"Yorum çok yerindeydi.","e2t":""},{"w":"aptitude","tr":"yetenek / yatkınlık / kabiliyet","te":"Noun","tt":"İsim","de":"A natural ability to do something","dt":"Bir şeyi yapabilme konusundaki doğal yetenek","e1":"An aptitude for mathematics.","e1t":"Matematiğe karşı yetenek (yatkınlık).","e2":"An aptitude test.","e2t":"Yetenek testi."},{"w":"aquiline","tr":"kartal gagası gibi / kavisli (burun)","te":"Adjective","tt":"Sıfat","de":"Like an eagle; (of a nose) curved like an eagle's beak","dt":"Kartal gibi; (burun için) kartal gagası gibi kavisli","e1":"He has a prominent aquiline nose.","e1t":"Belirgin, kavisli (kartal tipi) bir burnu var.","e2":"Aquiline features.","e2t":"Kartalvari yüz hatları."},{"w":"arable","tr":"ekilebilir / tarıma elverişli","te":"Adjective","tt":"Sıfat","de":"(Of land) used or suitable for growing crops","dt":"(Toprak için) mahsul yetiştirmek için kullanılan veya uygun olan","e1":"Arable land.","e1t":"Ekilebilir arazi.","e2":"Arable farming.","e2t":"Bitkisel üretim (tarla ziraatı)."},{"w":"arbiter","tr":"hakem / karar verici / söz sahibi","te":"Noun","tt":"İsim","de":"A person who settles a dispute or has ultimate authority in a matter","dt":"Bir anlaşmazlığı çözen veya bir konuda nihai yetkiye sahip olan kişi","e1":"The arbiter of fashion.","e1t":"Modada son sözü söyleyen kişi (moda otoritesi).","e2":"An impartial arbiter.","e2t":"Tarafsız bir hakem."},{"w":"arbitrate","tr":"hakemlik yapmak / arabuluculuk etmek","te":"Verb","tt":"Fiil","de":"(Of an independent person or body) reach an authoritative judgment or settlement","dt":"(Bağımsız bir kişi veya kurulun) yetkili bir yargıya veya çözüme varması","e1":"To arbitrate in a dispute.","e1t":"Bir anlaşmazlıkta hakemlik yapmak.","e2":"Arbitration (noun).","e2t":"Tahkim / Hakemlik."},{"w":"arboretum","tr":"ağaç parkı / fidanlık","te":"Noun","tt":"İsim","de":"A botanical garden devoted to trees","dt":"Ağaçlara adanmış botanik bahçesi","e1":"They visited the national arboretum.","e1t":"Ulusal ağaç parkını ziyaret ettiler.","e2":"An educational arboretum.","e2t":"Eğitici bir fidanlık/ağaç koleksiyonu."},{"w":"arcade","tr":"kemerli yol / pasaj / oyun salonu","te":"Noun","tt":"İsim","de":"A covered passage with arches; or a place with coin","dt":"operated games","e1":"Kemerli, üstü kapalı yol/pasaj; veya oyun makinelerinin bulunduğu yer","e1t":"A shopping arcade.","e2":"Alışveriş pasajı.","e2t":"Amusement arcade."},{"w":"arcane","tr":"gizemli / sır dolu / sadece uzmanların anladığı","te":"Adjective","tt":"Sıfat","de":"Understood by few; mysterious or secret","dt":"Az kişi tarafından anlaşılan; gizemli veya sır dolu","e1":"Arcane legal procedures.","e1t":"Kimsenin anlamadığı (karışık) yasal prosedürler.","e2":"Arcane knowledge.","e2t":"Gizli (kadim) bilgi."},{"w":"archaeology / archeology","tr":"arkeoloji / kazıbilim","te":"Noun","tt":"İsim","de":"The study of human history through the excavation of sites","dt":"Alan kazıları yoluyla insanlık tarihinin incelenmesi","e1":"A degree in archaeology.","e1t":"Arkeoloji diploması.","e2":"Archaeological find.","e2t":"Arkeolojik buluntu."},{"w":"archaic","tr":"çok eski / kadim / modası geçmiş","te":"Adjective","tt":"Sıfat","de":"Very old or old","dt":"fashioned","e1":"Çok eski veya eski moda","e1t":"An archaic word.","e2":"Artık kullanılmayan (eskimiş) kelime.","e2t":"Archaic customs."},{"w":"archetype","tr":"arketip / ilk örnek / asıl tip","te":"Noun","tt":"İsim","de":"A very typical example of a certain person or thing","dt":"Belirli bir kişi veya şeyin çok tipik bir örneği","e1":"He is the archetype of the successful businessman.","e1t":"Başarılı iş adamının prototipidir (arketipidir).","e2":"Jungian archetypes.","e2t":"Jungcu arketipler."},{"w":"archipelago","tr":"takımada","te":"Noun","tt":"İsim","de":"A group of islands","dt":"Adalar grubu","e1":"The Indonesian archipelago.","e1t":"Endonezya takımadaları.","e2":"A vast archipelago in the Pacific.","e2t":"Pasifik'te devasa bir takımada."},{"w":"archives","tr":"arşiv / sicil / kayıtlar","te":"Noun","tt":"İsim (Plural)","de":"A collection of historical documents or records","dt":"Tarihsel belgeler veya kayıtlar koleksiyonu","e1":"National archives.","e1t":"Ulusal arşivler.","e2":"To search through the family archives.","e2t":"Aile kayıtlarını araştırmak."},{"w":"argot","tr":"argo / jargon","te":"Noun","tt":"İsim","de":"The jargon or slang of a particular group or class","dt":"Belirli bir grup veya sınıfın jargonu veya argosu","e1":"Thieves' argot.","e1t":"Hırsızların kendi aralarındaki argosu.","e2":"Medical argot.","e2t":"Tıbbi jargon."},{"w":"aria","tr":"arya","te":"Noun","tt":"İsim","de":"A long accompanied song for a solo voice, typically in an opera","dt":"Genellikle operada, solo ses için söylenen uzun şarkı","e1":"She sang a beautiful aria.","e1t":"Güzel bir arya söyledi.","e2":"A soprano aria.","e2t":"Soprano aryası."},{"w":"arid","tr":"kurak / çorak / sıkıcı","te":"Adjective","tt":"Sıfat","de":"(Of land or a climate) having little or no rain; or lacking excitement","dt":"(Toprak veya iklim için) yağışsız; veya heyecansız (kurak)","e1":"Arid desert lands.","e1t":"Kurak çöl toprakları.","e2":"An arid discussion.","e2t":"Kısır (sıkıcı) bir tartışma."},{"w":"aristocracy","tr":"aristokrasi / soylular sınıfı","te":"Noun","tt":"İsim","de":"The highest class in certain societies, especially those holding hereditary titles","dt":"Bazı toplumlarda, özellikle babadan oğula geçen unvanlara sahip olan en üst sınıf","e1":"A member of the aristocracy.","e1t":"Aristokrasinin bir üyesi.","e2":"Landed aristocracy.","e2t":"Toprak sahibi soylular."},{"w":"armada","tr":"donanma / filo","te":"Noun","tt":"İsim","de":"A fleet of warships","dt":"Savaş gemileri filosu","e1":"The Spanish Armada.","e1t":"İspanyol Armada'sı.","e2":"An armada of fishing boats.","e2t":"Balıkçı tekneleri filosu."},{"w":"aromatic","tr":"aromatik / güzel kokulu","te":"Adjective","tt":"Sıfat","de":"Having a pleasant and distinctive smell","dt":"Hoş ve belirgin bir kokusu olan","e1":"Aromatic herbs.","e1t":"Aromatik (kokulu) bitkiler.","e2":"The aromatic smell of fresh coffee.","e2t":"Taze kahvenin o güzel kokusu."},{"w":"arraign","tr":"mahkemeye çağırmak / suçlamak / itham etmek","te":"Verb","tt":"Fiil","de":"Call or bring (someone) before a court to answer a criminal charge","dt":"Birini suçlamalara cevap vermesi için mahkemeye çıkarmak","e1":"He was arraigned on charges of corruption.","e1t":"Yolsuzluk suçlamasıyla hakim karşısına çıkarıldı.","e2":"Arraignment (noun).","e2t":"İtham / Sorgulama mahkemesi."},{"w":"array","tr":"sergilemek / dizmek / dizi / görkemli kıyafet","te":"Verb/Noun","tt":"Fiil/İsim","de":"An impressive display or range of a particular type of thing; or to arrange in order","dt":"Belirli bir türdeki şeylerin etkileyici sergisi; veya sıraya dizmek","e1":"A vast array of colors.","e1t":"Geniş bir renk yelpazesi (dizisi).","e2":"Soldiers arrayed for battle.","e2t":"Savaşa göre dizilmiş askerler."},{"w":"arrears","tr":"birikmiş borç / gecikmiş ödeme","te":"Noun","tt":"İsim (Plural)","de":"Money that is owed and should have been paid earlier","dt":"Vadesi geçmiş ve daha önce ödenmesi gereken borç","e1":"To be in arrears with the rent.","e1t":"Kira borcu birikmiş olmak.","e2":"Rent arrears.","e2t":"Kira borçları."},{"w":"arrhythmic","tr":"ritimsiz / düzensiz","te":"Adjective","tt":"Sıfat","de":"Not rhythmic; without a regular pattern","dt":"Ritmik olmayan; düzenli bir yapısı olmayan","e1":"Arrhythmic breathing.","e1t":"Düzensiz (ritimsiz) nefes alma.","e2":"Arrhythmic heartbeat.","e2t":"Kalp ritim bozukluğu."},{"w":"arrogance","tr":"kibir / küstahlık","te":"Noun","tt":"İsim","de":"The quality of being unpleasantly proud and behaving as if you are more important than others","dt":"Başkalarından daha önemliymiş gibi davranma ve nahoş bir gurur duyma niteliği","e1":"His arrogance alienated many people.","e1t":"Küstahlığı birçok kişiyi kendinden uzaklaştırdı.","e2":"Intellectual arrogance.","e2t":"Entelektüel kibir."},{"w":"arroyo","tr":"dere yatağı (genellikle kuru)","te":"Noun","tt":"İsim","de":"A steep","dt":"sided gully cut by running water in an arid or semi","e1":"arid region","e1t":"Kurak bölgelerde suyun aşındırmasıyla oluşan dik kenarlı dere yatağı","e2":"The dry arroyo filled quickly during the rain.","e2t":"Kuru dere yatağı yağmur sırasında hızla doldu."},{"w":"arsenal","tr":"cephanelik / silah deposu","te":"Noun","tt":"İsim","de":"A collection of weapons and military equipment","dt":"Silah ve askeri teçhizat koleksiyonu","e1":"A nuclear arsenal.","e1t":"Nükleer cephanelik.","e2":"To have a vast arsenal of arguments.","e2t":"Geniş bir argüman deposuna (çeşitli fikirlere) sahip olmak."},{"w":"artifact / artefact","tr":"insan eliyle yapılmış nesne / tarihi eser","te":"Noun","tt":"İsim","de":"An object made by a human being, typically one of cultural or historical interest","dt":"İnsan tarafından yapılmış, genellikle kültürel veya tarihsel ilgi uyandıran nesne","e1":"Ancient Egyptian artifacts.","e1t":"Antik Mısır eserleri.","e2":"Archeologists found several stone artifacts.","e2t":"Arkeologlar birkaç taş eser buldu."},{"w":"artifice","tr":"hile / kurnazlık / beceri","te":"Noun","tt":"İsim","de":"Clever or cunning devices or expedients, especially as used to trick or deceive others","dt":"Özellikle başkalarını kandırmak için kullanılan zekice veya kurnazca yöntemler","e1":"A political artifice.","e1t":"Siyasi bir hile.","e2":"Without artifice (honestly).","e2t":"Hilesiz (dürüstçe)."},{"w":"artisan","tr":"zanaatkar / usta","te":"Noun","tt":"İsim","de":"A worker in a skilled trade, especially one that involves making things by hand","dt":"Özellikle el emeğiyle bir şeyler yapmayı içeren bir zanaatta çalışan kişi","e1":"Local artisans selling their jewelry.","e1t":"Takılarını satan yerel zanaatkarlar.","e2":"Artisan bread.","e2t":"Geleneksel yöntemle yapılmış (zanaat işi) ekmek."},{"w":"artless","tr":"saf / doğal / hilesiz","te":"Adjective","tt":"Sıfat","de":"Without guile or deception; natural and simple","dt":"Hilesiz ve yalansız; doğal ve basit","e1":"Her artless charm.","e1t":"Onun yapmacıksız (doğal) cazibesi.","e2":"An artless remark.","e2t":"Safça (hesapsızca) söylenmiş bir söz."},{"w":"ascendancy / ascendency","tr":"üstünlük / egemenlik / nüfuz","te":"Noun","tt":"İsim","de":"Occupation of a position of dominant power or influence","dt":"Baskın bir güç veya nüfuz konumunda olma","e1":"To gain ascendancy over one's rivals.","e1t":"Rakiplerine karşı üstünlük kurmak.","e2":"The moral ascendancy of the leader.","e2t":"Liderin ahlaki üstünlüğü."},{"w":"ascetic","tr":"münzevi / çileci / sofu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Characterized by severe self","dt":"discipline and abstention from all forms of indulgence","e1":"Sert bir özdisiplin ve her türlü zevkten kaçınma ile karakterize edilen","e1t":"An ascetic lifestyle.","e2":"Çileci (münzevi) bir yaşam tarzı.","e2t":"The monks live an ascetic life."},{"w":"aseptic","tr":"aseptik / mikropsuz / steril","te":"Adjective","tt":"Sıfat","de":"Free from contamination caused by harmful bacteria, viruses, or other microorganisms","dt":"Zararlı bakteri veya mikroorganizmalardan arınmış","e1":"Aseptic surgery.","e1t":"Aseptik (mikropsuz) cerrahi.","e2":"Aseptic packaging.","e2t":"Steril paketleme."},{"w":"ashen","tr":"kül rengi / çok solgun","te":"Adjective","tt":"Sıfat","de":"(Of a person's face) very pale with shock, fear, or illness","dt":"(Yüz için) şok, korku veya hastalıktan dolayı çok solgun","e1":"Her face turned ashen when she heard the news.","e1t":"Haberi duyunca yüzü kül gibi oldu (bembeyaz kesildi).","e2":"Ashen sky.","e2t":"Kül rengi gökyüzü."},{"w":"asinine","tr":"aptalca / eşekçe / anlamsız","te":"Adjective","tt":"Sıfat","de":"Extremely stupid or foolish","dt":"Son derece aptalca veya saçma","e1":"An asinine comment.","e1t":"Aptalca bir yorum.","e2":"Stop making asinine suggestions.","e2t":"Saçma sapan öneriler sunmayı bırak."},{"w":"askance","tr":"şüpheyle / kuşkuyla / yan gözle","te":"Adverb","tt":"Zarf","de":"With an attitude or look of suspicion or disapproval","dt":"Şüphe veya onaylamama ifadesiyle","e1":"To look askance at a proposal.","e1t":"Bir öneriye kuşkuyla (yan gözle) bakmak.","e2":"They viewed the new rules askance.","e2t":"Yeni kuralları şüpheyle karşıladılar."},{"w":"askew","tr":"eğri / yamuk / çarpık","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Not in a straight or level position","dt":"Düz veya dengeli olmayan bir konumda","e1":"His tie was askew.","e1t":"Kravatı yamuktu.","e2":"To look askew.","e2t":"Yan bakmak / Eğri durmak."},{"w":"asperity","tr":"sertlik / şiddet / hırçınlık (mizaç)","te":"Noun","tt":"İsim","de":"Harshness of tone or manner","dt":"Ses tonu veya tavırdaki sertlik","e1":"To speak with some asperity.","e1t":"Sert bir tavırla (hırçınlıkla) konuşmak.","e2":"The asperities of the climate.","e2t":"İklimin sertliği (zorlukları)."},{"w":"aspersion","tr":"iftira / leke sürme / karalama","te":"Noun","tt":"İsim","de":"An attack on the reputation or integrity of someone or something","dt":"Birinin itibarına veya dürüstlüğüne yönelik saldırı","e1":"To cast aspersions on someone's character.","e1t":"Birinin karakterine dil uzatmak (kara çalmak).","e2":"He denied the aspersions.","e2t":"Karalamaları reddetti."},{"w":"aspirant","tr":"aday / hevesli / talip","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has ambitions to achieve something","dt":"Bir şeyi başarma hırsı olan kişi (aday)","e1":"An aspirant to the throne.","e1t":"Tahtın talibi (adayı).","e2":"Presidential aspirants.","e2t":"Başkan adayları."},{"w":"assail","tr":"saldırmak / üzerine çullanmak / (soru vb.) yağmuruna tutmak","te":"Verb","tt":"Fiil","de":"Make a concerted or violent attack on","dt":"Şiddetli veya organize bir saldırıda bulunmak","e1":"To assail an enemy stronghold.","e1t":"Düşman kalesine saldırmak.","e2":"Assailed by doubts.","e2t":"Şüphelerin saldırısına uğramış (şüphe içinde kalmış)."},{"w":"assay","tr":"tahlil etmek / ayar belirlemek / deneme","te":"Verb/Noun","tt":"Fiil/İsim","de":"Determine the content or quality of (a metal or ore)","dt":"(Metal veya cevherin) içeriğini veya kalitesini belirlemek (ayarını ölçmek)","e1":"To assay the purity of gold.","e1t":"Altının saflığını tahlil etmek (ayarını ölçmek).","e2":"A biological assay.","e2t":"Biyolojik deney/tahlil."},{"w":"assent","tr":"onay / kabul / razı olmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The expression of approval or agreement","dt":"Onay veya anlaşma ifadesi","e1":"The director gave his assent to the proposal.","e1t":"Direktör öneriye onayını (kabulünü) verdi.","e2":"To murmur assent.","e2t":"Onayladığını fısıldamak."},{"w":"assiduous","tr":"çalışkan / gayretli / titiz","te":"Adjective","tt":"Sıfat","de":"Showing great care and perseverance","dt":"Büyük özen ve azim gösteren","e1":"Assiduous research.","e1t":"Titiz (gayretli) araştırma.","e2":"She was assiduous in her duties.","e2t":"Görevlerinde çok çalışkandı."},{"w":"assuage","tr":"yatıştırmak / dindirmek / hafifletmek","te":"Verb","tt":"Fiil","de":"Make (an unpleasant feeling) less intense","dt":"(Nahoş bir duyguyu) daha az şiddetli kılmak","e1":"To assuage someone's grief.","e1t":"Birinin kederini hafifletmek.","e2":"To assuage your hunger.","e2t":"Açlığını dindirmek."},{"w":"asteroid","tr":"asteroid / gök taşı","te":"Noun","tt":"İsim","de":"A small rocky body orbiting the sun","dt":"Güneşin etrafında dönen küçük kayalık cisim","e1":"The asteroid belt between Mars and Jupiter.","e1t":"Mars ve Jüpiter arasındaki asteroid kuşağı.","e2":"An asteroid impact.","e2t":"Asteroid çarpması."},{"w":"astigmatism","tr":"astigmatizm / göz kusuru","te":"Noun","tt":"İsim","de":"A defect in the eye or in a lens caused by a deviation from spherical curvature","dt":"Küresel kavis sapması nedeniyle gözde veya mercekte oluşan kusur","e1":"He wears glasses to correct his astigmatism.","e1t":"Astigmatını düzeltmek için gözlük takıyor.","e2":"Blurred vision due to astigmatism.","e2t":"Astigmatizm kaynaklı bulanık görme."},{"w":"astral","tr":"yıldızlarla ilgili / yıldızvari","te":"Adjective","tt":"Sıfat","de":"Relating to the stars","dt":"Yıldızlarla ilgili","e1":"Astral navigation.","e1t":"Yıldızlarla seyrüsefer.","e2":"Astral projection.","e2t":"Astral seyahat (beden dışı deneyim)."},{"w":"astringent","tr":"büzücü / sıkılaştırıcı / keskin (eleştiri)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Causing the contraction of skin cells; or sharp and severe","dt":"Cilt hücrelerinin kasılmasına neden olan; veya keskin ve sert","e1":"An astringent lotion for oily skin.","e1t":"Yağlı ciltler için sıkılaştırıcı (büzücü) losyon.","e2":"Astringent criticism.","e2t":"Keskin (sert) eleştiri."},{"w":"astronomical","tr":"astronomik / gökbilimsel / devasa","te":"Adjective","tt":"Sıfat","de":"Relating to astronomy; or (of an amount) extremely large","dt":"Gökbilimi ile ilgili; veya (miktar için) son derece büyük","e1":"Astronomical observations.","e1t":"Astronomik gözlemler.","e2":"The costs are astronomical.","e2t":"Maliyetler astronomik (çok yüksek)."},{"w":"asunder","tr":"ayrı / paramparça / ayrı taraflara","te":"Adverb","tt":"Zarf","de":"Apart; divided; or into pieces","dt":"Ayrı; bölünmüş; veya parçalara ayrılmış","e1":"A family torn asunder by war.","e1t":"Savaşla parçalanmış (ayrılmış) bir aile.","e2":"To burst asunder.","e2t":"Paramparça olmak."},{"w":"asymmetric","tr":"asimetrik / simetrik olmayan","te":"Adjective","tt":"Sıfat","de":"Having parts or aspects that are not the same or do not match in size, shape, or position","dt":"Boyut, şekil veya konum bakımından aynı olmayan veya eşleşmeyen parçalara sahip olan","e1":"Asymmetric wings.","e1t":"Asimetrik kanatlar.","e2":"Asymmetric information (economics).","e2t":"Asimetrik bilgi."},{"w":"atavism","tr":"atavizm / atalara çekme / geriye dönme","te":"Noun","tt":"İsim","de":"A tendency to revert to something ancient or ancestral; or a recurrence of a trait from a remote ancestor","dt":"Kadim veya atalara ait bir şeye geri dönme eğilimi; veya uzak bir atadan gelen bir özelliğin tekrar ortaya çıkması","e1":"The atavism of certain biological traits.","e1t":"Bazı biyolojik özelliklerin atalara çekmesi.","e2":"Atavistic fears (ancient).","e2t":"İlkel (atalardan kalma) korkular."},{"w":"atheism","tr":"ateizm / tanrıtanımazlık","te":"Noun","tt":"İsim","de":"Disbelief or lack of belief in the existence of God or gods","dt":"Tanrı'nın veya tanrıların varlığına inanmama veya inanç eksikliği","e1":"He was a lifelong supporter of atheism.","e1t":"Hayatı boyunca ateizmin destekçisiydi.","e2":"Militant atheism.","e2t":"Militan ateizm."},{"w":"atone","tr":"telafi etmek / (günahını) ödemek / kefaret etmek","te":"Verb","tt":"Fiil","de":"To make amends or reparation for an offense or a crime","dt":"Bir suç veya hata için telafi veya onarım yapmak","e1":"To atone for your sins.","e1t":"Günahların için kefaret etmek.","e2":"He tried to atone for his past mistakes.","e2t":"Geçmiş hatalarını telafi etmeye çalıştı."},{"w":"atrocity","tr":"vahşet / zulüm / gaddarlık","te":"Noun","tt":"İsim","de":"An extremely wicked or cruel act, typically one involving physical violence or injury","dt":"Genellikle fiziksel şiddet içeren, son derece kötü veya zalimce eylem","e1":"War atrocities.","e1t":"Savaş vahşeti (zulmü).","e2":"To commit an atrocity.","e2t":"Vahşet işlemek."},{"w":"atrophy","tr":"körelme / zayıflama / atrofi","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of body tissue or an organ) waste away, especially as a result of the degeneration of cells; or to decline in effectiveness","dt":"(Vücut dokusu veya organı için) hücrelerin dejenere olması sonucu erimek; veya etkinlikte gerilemek","e1":"Muscles can atrophy from lack of exercise.","e1t":"Egzersiz eksikliğinden kaslar körelebilir (eriyebilir).","e2":"The atrophy of our creative skills.","e2t":"Yaratıcı becerilerimizin zayıflaması."},{"w":"attenuate","tr":"zayıflatmak / etkisini azaltmak / inceltmek","te":"Verb","tt":"Fiil","de":"Reduce the force, effect, or value of; or to make thin","dt":"Gücü, etkiyi veya değeri azaltmak; veya inceltmek","e1":"To attenuate a signal.","e1t":"Bir sinyali zayıflatmak.","e2":"The effects of the drug were attenuated over time.","e2t":"İlacın etkileri zamanla azaldı."},{"w":"attire","tr":"giyim kuşam / kıyafet / giydirmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Clothes, especially fine or formal ones; or to dress someone","dt":"Giysi, özellikle şık veya resmi olanlar; veya birini giydirmek","e1":"Formal attire is required.","e1t":"Resmi kıyafet gereklidir.","e2":"In their holiday attire.","e2t":"Bayramlık kıyafetleri içinde."},{"w":"attrition","tr":"aşınma / yıpranma / eksilme / zayiat","te":"Noun","tt":"İsim","de":"The process of reducing something's strength or effectiveness through sustained attack or pressure; or a gradual reduction in staff","dt":"Sürekli saldırı veya baskı yoluyla bir şeyin gücünü azaltma süreci; veya personelin kademeli olarak azalması","e1":"A war of attrition.","e1t":"Yıpratma savaşı.","e2":"Staff attrition (natural).","e2t":"Personelin (istifa/emeklilik yoluyla) doğal eksilmesi."},{"w":"audition","tr":"seçme / deneme (oyunculuk vb.)","te":"Noun/Verb","tt":"İsim/Fiil","de":"An interview for a role as a singer, actor, dancer, etc.; or to perform in one","dt":"Şarkıcı, oyuncu veya dansçı rolü için yapılan mülakat/deneme; veya seçmeye girmek","e1":"To have an audition for a play.","e1t":"Bir oyun için seçmelere girmek.","e2":"Hundreds of people auditioned for the role.","e2t":"Rol için yüzlerce kişi denemeye girdi."},{"w":"augur","tr":"işaret etmek / kehanette bulunmak / haberci","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of an event or circumstance) portend a good or bad outcome; or a religious official who interpreted omens","dt":"(Olay veya durum için) iyi veya kötü bir sonuca işaret etmek; veya (tarihi) kahin/falcı","e1":"This decision augurs ill for the peace process.","e1t":"Bu karar barış süreci için kötüye işaret ediyor.","e2":"To augur well for the future.","e2t":"Gelecek için hayra alamet olmak."},{"w":"augury","tr":"kehanet / fal / belirti","te":"Noun","tt":"İsim","de":"A sign of what will happen in the future; an omen","dt":"Gelecekte ne olacağına dair işaret; belirti","e1":"To read the auguries.","e1t":"Belirtileri (kehanetleri) okumak.","e2":"An augury of success.","e2t":"Başarı belirtisi."},{"w":"aura","tr":"aura / hava / atmosfer","te":"Noun","tt":"İsim","de":"The distinctive atmosphere or quality that seems to surround and be generated by a person, thing, or place","dt":"Bir kişi, nesne veya yeri çevrelediği ve ondan yayıldığı düşünülen kendine özgü hava","e1":"An aura of mystery.","e1t":"Bir gizem havası (aurası).","e2":"She has a calm aura.","e2t":"Sakin bir aurası (havası) var."},{"w":"aural","tr":"kulakla ilgili / işitsel","te":"Adjective","tt":"Sıfat","de":"Relating to the ear or the sense of hearing","dt":"Kulakla veya işitme duyusuyla ilgili","e1":"Aural perception.","e1t":"İşitsel algı.","e2":"Aural skills.","e2t":"İşitme becerileri."},{"w":"aurora","tr":"tan / şafak / kutup ışıkları","te":"Noun","tt":"İsim","de":"A natural electrical phenomenon characterized by the appearance of streamers of reddish or greenish light in the sky","dt":"Gökyüzünde kırmızımsı veya yeşilimsi ışık akışlarının görünmesiyle karakterize edilen doğal elektriksel fenomen","e1":"Aurora borealis (Northern lights).","e1t":"Kuzey ışıkları.","e2":"Aurora australis (Southern lights).","e2t":"Güney ışıkları."},{"w":"auspice","tr":"himaye / koruma / belirti","te":"Noun","tt":"İsim","de":"A divine or prophetic token; or (usually plural) protection and support","dt":"İlahi veya kehanet niteliğinde işaret; veya (genellikle çoğul) koruma ve destek","e1":"Under the auspices of the government.","e1t":"Hükümetin himayesi (gözetimi) altında.","e2":"Auspicious (adjective).","e2t":"Hayırlı / Uğurlu."},{"w":"austerity","tr":"kemer sıkma / sertlik / sadelik","te":"Noun","tt":"İsim","de":"Sternness or severity of manner or attitude; or extreme plainness; or difficult economic conditions","dt":"Tavır veya tutumdaki sertlik; veya aşırı sadelik; veya zor ekonomik koşullar","e1":"Wartime austerity.","e1t":"Savaş zamanı kemer sıkma dönemi.","e2":"The austerity of the design.","e2t":"Tasarımın sadeliği."},{"w":"authenticate","tr":"doğrulamak / aslına kanıtlamak","te":"Verb","tt":"Fiil","de":"Prove or show something to be true, genuine, or valid","dt":"Bir şeyin doğru, gerçek veya geçerli olduğunu kanıtlamak veya göstermek","e1":"To authenticate a signature.","e1t":"Bir imzayı doğrulamak.","e2":"Experts were called in to authenticate the painting.","e2t":"Tablonun orijinalliğini kanıtlamak için uzmanlar çağrıldı."},{"w":"authoritarian","tr":"otoriter / baskıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Favoring or enforcing strict obedience to authority, especially that of the government","dt":"Otoriteye, özellikle hükümetinkine, sıkı itaati destekleyen veya dayatan","e1":"An authoritarian regime.","e1t":"Otoriter bir rejim.","e2":"Authoritarian parents.","e2t":"Baskıcı (otoriter) ebeveynler."},{"w":"authoritative","tr":"yetkili / güvenilir / buyurgan","te":"Adjective","tt":"Sıfat","de":"Able to be trusted as being accurate or true; reliable; or commanding and self","dt":"confident","e1":"Doğru veya gerçek olduğuna güvenilebilen; güvenilir; veya emir veren ve kendinden emin","e1t":"An authoritative source.","e2":"Güvenilir (yetkili) bir kaynak.","e2t":"His voice was firm and authoritative."},{"w":"autocrat","tr":"otokrat / diktatör / mutlak yönetici","te":"Noun","tt":"İsim","de":"A ruler who has absolute power","dt":"Mutlak güce sahip olan yönetici","e1":"He ruled as an absolute autocrat.","e1t":"Mutlak bir otokrat olarak hüküm sürdü.","e2":"To be a bit of an autocrat in the office.","e2t":"Ofiste biraz diktatör gibi davranmak."},{"w":"automaton","tr":"otomat / robot gibi davranan kişi","te":"Noun","tt":"İsim","de":"A moving mechanical device made in imitation of a human being; or a person who acts in a mechanical way","dt":"İnsan taklidi yapılarak üretilmiş hareketli mekanik düzenek; veya mekanik bir şekilde hareket eden kişi","e1":"Like a soulless automaton.","e1t":"Ruhsuz bir otomat gibi.","e2":"The industrial automata.","e2t":"Endüstriyel otomatlar (robotlar)."},{"w":"autonomous","tr":"özerk / otonom / bağımsız","te":"Adjective","tt":"Sıfat","de":"(Of a country or region) having the freedom to govern itself or control its own affairs; or acting independently","dt":"(Ülke veya bölge için) kendi kendini yönetme veya kendi işlerini kontrol etme özgürlüğüne sahip; veya bağımsız hareket eden","e1":"An autonomous region.","e1t":"Özerk bölge.","e2":"Autonomous vehicles (self","e2t":"driving)."},{"w":"avarice","tr":"açgözlülük / hırs / mal hırsı","te":"Noun","tt":"İsim","de":"Extreme greed for wealth or material gain","dt":"Servet veya maddi kazanç için aşırı açgözlülük","e1":"He was motivated by pure avarice.","e1t":"Tamamen açgözlülükle hareket etti.","e2":"Avaricious (adjective).","e2t":"Açgözlü / Paragöz."},{"w":"avenge","tr":"intikamını almak","te":"Verb","tt":"Fiil","de":"Inflict harm in return for an injury or wrong done to oneself or another","dt":"Kendisine veya başkasına yapılan bir zarar veya yanlışın karşılığında zarar vermek","e1":"To avenge his father's death.","e1t":"Babasının ölümünün intikamını almak.","e2":"He vowed to avenge the insult.","e2t":"Hakaretin öcünü almaya yemin etti. (Not: 'Revenge' isim hali için daha yaygındır)."},{"w":"aver","tr":"ileri sürmek / beyan etmek / iddia etmek","te":"Verb","tt":"Fiil","de":"State or assert to be the case (formal)","dt":"Durumun öyle olduğunu beyan etmek veya iddia etmek (resmi)","e1":"He averred that he was innocent.","e1t":"Masum olduğunu beyan etti (ileri sürdü).","e2":"To aver a fact.","e2t":"Bir gerçeği doğrulamak."},{"w":"averse","tr":"isteksiz / karşı / soğuk bakan","te":"Adjective","tt":"Sıfat","de":"Having a strong dislike of or opposition to something","dt":"Bir şeye karşı güçlü bir hoşnutsuzluk veya karşıtlık duyma","e1":"I am not averse to a drink now and then.","e1t":"Ara sıra içmeye karşı değilim.","e2":"Risk","e2t":"averse."},{"w":"aviary","tr":"kuş kafesi / kuşluk","te":"Noun","tt":"İsim","de":"A large cage, building, or enclosure for keeping birds in","dt":"Kuşları beslemek için büyük kafes veya bina","e1":"They visited the exotic aviary.","e1t":"Egzotik kuşluğu ziyaret ettiler.","e2":"A walk","e2t":"in aviary."},{"w":"avocation","tr":"yan uğraş / hobi / iş (ikincil)","te":"Noun","tt":"İsim","de":"A hobby or minor occupation","dt":"Hobi veya küçük uğraş","e1":"Gardening is her favorite avocation.","e1t":"Bahçecilik onun en sevdiği yan uğraşıdır.","e2":"To pursue an avocation.","e2t":"Bir hobiyle ilgilenmek. (Not: 'Vocation' asıl meslek demektir)."},{"w":"avow","tr":"açıkça söylemek / itiraf etmek / ikrar etmek","te":"Verb","tt":"Fiil","de":"Assert or confess openly","dt":"Açıkça iddia etmek veya itiraf etmek","e1":"He avowed his commitment to the cause.","e1t":"Davaya olan bağlılığını açıkça belirtti.","e2":"An avowed atheist.","e2t":"İnancını saklamayan (açık) bir ateist."},{"w":"avuncular","tr":"amca gibi / babacan / nazik","te":"Adjective","tt":"Sıfat","de":"Suggesting the presence of a kind and friendly uncle","dt":"Nazik ve dost canlısı bir amcanın varlığını çağrıştıran (babacan)","e1":"An avuncular smile.","e1t":"Babacan bir gülümseme.","e2":"He gave some avuncular advice.","e2t":"Amca tavsiyesi gibi nazik öğütler verdi."},{"w":"awry","tr":"eğri / yamuk / ters (gitmek)","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Away from the appropriate, planned, or expected course; amiss; or twisted to one side","dt":"Uygun, planlanan veya beklenen rotadan uzak; ters (gitmek); veya bir yana bükülmüş","e1":"Our plans went awry.","e1t":"Planlarımız ters gitti.","e2":"Her hat was slightly awry.","e2t":"Şapkası biraz yamuktu."},{"w":"axiom","tr":"aksiyom / belit / temel ilke","te":"Noun","tt":"İsim","de":"A statement or proposition which is regarded as being established, accepted, or self","dt":"evidently true","e1":"Doğruluğu açıkça belli olan, kanıtlanmaya gerek duyulmadan kabul edilen temel gerçek","e1t":"It is a political axiom that power corrupts.","e2":"Gücün yozlaştırdığı siyasi bir aksiyomdur.","e2t":"To take something as an axiom."},{"w":"axis","tr":"eksen / dingil / ittifak","te":"Noun","tt":"İsim","de":"An imaginary line about which a body rotates; or a fixed reference line for the measurement of coordinates","dt":"Bir cismin etrafında döndüğü hayali çizgi; veya koordinat ölçümü için sabit referans çizgisi","e1":"The Earth's axis.","e1t":"Dünya'nın ekseni.","e2":"The X and Y axes (plural: axes).","e2t":"X ve Y eksenleri."},{"w":"azure","tr":"gök mavisi / masmavi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Bright blue in color, like a cloudless sky","dt":"Bulutsuz bir gökyüzü gibi parlak mavi renk","e1":"The azure waters of the Mediterranean.","e1t":"Akdeniz'in masmavi suları.","e2":"An azure sky.","e2t":"Gök mavisi bir gökyüzü."},{"w":"babble","tr":"gevezelik etmek / anlaşılmaz konuşmak / şırıldamak (su)","te":"Verb/Noun","tt":"Fiil/İsim","de":"Talk rapidly and continuously in a foolish, excited, or incomprehensible way","dt":"Aptalca, heyecanlı veya anlaşılmaz bir şekilde sürekli ve hızlı konuşmak","e1":"What is he babbling about?","e1t":"Neden bahsedip duruyor (ne geveliyor)?","e2":"The babbling of a brook.","e2t":"Bir derenin şırıltısı."},{"w":"bacchanalian","tr":"içkili ve gürültülü eğlence / aleme ait","te":"Adjective","tt":"Sıfat","de":"Characterized by or given to drunken revelry","dt":"İçkili, gürültülü ve aşırı eğlence ile karakterize edilen","e1":"A bacchanalian party.","e1t":"İçkili ve taşkın bir parti.","e2":"Bacchanalian rites.","e2t":"Baküs şenlikleri (taşkın törenler)."},{"w":"badger","tr":"porsuk / rahatsız etmek / kafa ütülemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Ask someone repeatedly and annoyingly for something; pester","dt":"Birinden bir şeyi ısrarla ve rahatsız edici şekilde istemek; musallat olmak","e1":"Stop badgering me!","e1t":"Beni darlamayı (rahatsız etmeyi) bırak!","e2":"He badgered his parents for a new phone.","e2t":"Yeni bir telefon için ailesinin kafasını ütüledi."},{"w":"badinage","tr":"şaka / nükte / latife","te":"Noun","tt":"İsim","de":"Humorous or witty conversation","dt":"Mizahi veya zekice (şakacı) konuşma","e1":"A bit of light badinage.","e1t":"Hafif bir şakalaşma.","e2":"Confident badinage.","e2t":"Kendinden emin nükteler."},{"w":"bagatelle","tr":"önemsiz şey / ıvır zıvır / kolay iş","te":"Noun","tt":"İsim","de":"A thing of little importance; or a very easy task","dt":"Çok az önemi olan şey; veya çok kolay bir görev","e1":"A mere bagatelle.","e1t":"Sadece ufak tefek bir şey (önemsiz).","e2":"For him, the exam was a bagatelle.","e2t":"Sınav onun için çocuk oyuncağıydı."},{"w":"bailiff","tr":"icra memuru / kahya / mübaşir","te":"Noun","tt":"İsim","de":"An official in a court of law who keeps order, looks after prisoners, etc.; or a manager of an estate","dt":"Mahkemede düzeni sağlayan görevli; veya bir mülkün yöneticisi/kahyası","e1":"The bailiff took the property.","e1t":"İcra memuru mallara el koydu.","e2":"The court bailiff.","e2t":"Mahkeme mübaşiri."},{"w":"bait","tr":"yem / yemlemek / kışkırtmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Food placed on a hook or in a net to entice fish or other animals; or to deliberately annoy someone","dt":"Balık veya hayvanları cezbetmek için kancaya/ağa konulan yiyecek; veya birini kasten kızdırmak","e1":"To take the bait.","e1t":"Yemi yutmak (tuzağa düşmek).","e2":"To bait a hook.","e2t":"Oltaya yem takmak."},{"w":"baleful","tr":"kötücül / tehditkar / uğursuz","te":"Adjective","tt":"Sıfat","de":"Threatening harm; menacing","dt":"Zarar verecekmiş gibi tehdit eden; kötü niyetli","e1":"A baleful look.","e1t":"Tehditkar (kötücül) bir bakış.","e2":"Baleful influence.","e2t":"Kötü (zararlı) etki."},{"w":"balk","tr":"tereddüt etmek / ayak diremek / engel olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Hesitate or be unwilling to accept an idea or undertaking; or to hinder","dt":"Bir fikri veya işi kabul etmeye isteksiz olmak (çekinmek); veya engellemek","e1":"He balked at the high price.","e1t":"Yüksek fiyat karşısında tereddüt etti (geri adım attı).","e2":"To balk a plan.","e2t":"Bir planı suya düşürmek."},{"w":"ballast","tr":"balast / denge ağırlığı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Heavy substance used to improve the stability of a ship or the center of gravity of an aerostat","dt":"Bir geminin dengesini sağlamak veya bir hava aracının ağırlık merkezini ayarlamak için kullanılan ağır madde","e1":"The ship took on water as ballast.","e1t":"Gemi denge ağırlığı (balast) olarak su aldı.","e2":"Emotional ballast (something that gives stability).","e2t":"Duygusal denge (istikrar sağlayan şey)."},{"w":"balm","tr":"balsam / merhem / huzur verici şey","te":"Noun","tt":"İsim","de":"A fragrant ointment or preparation used to heal or soothe the skin; or something that provides comfort","dt":"Cildi iyileştirmek veya yatıştırmak için kullanılan güzel kokulu merhem; veya teselli veren şey","e1":"Lip balm.","e1t":"Dudak kremi.","e2":"The music was a balm to his soul.","e2t":"Müzik ruhuna bir merhem (huzur) gibi geldi."},{"w":"banal","tr":"banal / sıradan / basmakalıp","te":"Adjective","tt":"Sıfat","de":"So lacking in originality as to be obvious and boring","dt":"Orijinallikten uzak, bariz ve sıkıcı olan","e1":"A banal remark.","e1t":"Basmakalıp (sıradan) bir söz.","e2":"The plot was rather banal.","e2t":"Hikaye oldukça sıradandı."},{"w":"bandy","tr":"tartışmak / söz dalaşı yapmak / eğri (bacak)","te":"Verb/Adjective","tt":"Pass on or discuss (an idea or rumor) in an uninformed or casual way; or (of legs) curved outwards","de":"Bir fikri veya söylentiyi (genellikle düşüncesizce) ortaya atmak veya tartışmak; veya (bacaklar için) dışa doğru kavisli","dt":"To bandy words with someone.","e1":"Biriyle söz dalaşına girmek (tartışmak).","e1t":"His name was bandied about.","e2":"Adı dillerde dolaştı (hakkında konuşuldu).","e2t":""},{"w":"bane","tr":"bela / dert / yıkım nedeni","te":"Noun","tt":"İsim","de":"A cause of great distress or annoyance","dt":"Büyük sıkıntı veya rahatsızlık nedeni","e1":"The bane of my existence.","e1t":"Hayatımın baş belası.","e2":"Snails are the bane of gardeners.","e2t":"Salyangozlar bahçıvanların kabusudur (derdi)."},{"w":"barb","tr":"diken (tel/ok) / iğneleyici söz","te":"Noun","tt":"İsim","de":"A sharp projection near the end of an arrow, fish hook, etc.; or a cutting remark","dt":"Ok, olta vb. ucundaki sivri çıkıntı; veya incitici/iğneleyici söz","e1":"The barb of the hook.","e1t":"Oltanın dikeni (çengeli).","e2":"To exchange barbs.","e2t":"Karşılıklı iğneleyici laflar sokmak."},{"w":"bard","tr":"ozan / şair","te":"Noun","tt":"İsim","de":"A poet, traditionally one reciting epics and associated with a particular oral tradition","dt":"Geleneksel olarak destanlar okuyan şair","e1":"The Bard of Avon (Shakespeare).","e1t":"Avon Ozanı (Shakespeare).","e2":"Ancient bards.","e2t":"Antik ozanlar."},{"w":"barefaced","tr":"küstah / arsız / utanmazca","te":"Adjective","tt":"Sıfat","de":"Shameless and undisguised","dt":"Utanmaz ve gizlenmemiş","e1":"A barefaced lie.","e1t":"Arsızca (apaçık) bir yalan.","e2":"Barefaced impudence.","e2t":"Küstahça arsızlık."},{"w":"baritone","tr":"bariton / orta kalınlıkta erkek sesi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An adult male singing voice between tenor and bass","dt":"Tenor ile bas arasındaki yetişkin erkek sesi","e1":"He has a rich baritone voice.","e1t":"Dolgun bir bariton sesi var.","e2":"Baritone saxophone.","e2t":"Bariton saksofon."},{"w":"baroque","tr":"barok / aşırı süslü / karmaşık","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to a highly ornate and extravagant style of European architecture, music, and art","dt":"Avrupa mimarisi, müziği ve sanatında oldukça süslü ve abartılı bir tarzla ilgili","e1":"Baroque architecture.","e1t":"Barok mimarisi.","e2":"A baroque prose style (complicated).","e2t":"Karmaşık (aşırı süslü) bir nesir tarzı."},{"w":"barrister","tr":"dava vekili / avukat (üst mahkeme)","te":"Noun","tt":"İsim","de":"A lawyer entitled to practice as an advocate, particularly in the higher courts","dt":"Özellikle üst mahkemelerde savunmanlık yapma yetkisi olan avukat","e1":"He consulted a barrister.","e1t":"Bir dava vekiline (avukata) danıştı. (Not: İngiliz hukuk sisteminde 'solicitor'dan farklıdır).","e2":"","e2t":""},{"w":"bask","tr":"güneşlenmek / (ilgi/başarı) tadını çıkarmak","te":"Verb","tt":"Fiil","de":"Lie exposed to warmth and light, typically from the sun, for relaxation; or to enjoy approval","dt":"Rahatlamak için güneş ışığına veya ısıya maruz kalmak; veya onayın/başarının tadını çıkarmak","e1":"To bask in the sun.","e1t":"Güneşlenmek.","e2":"To bask in the glory of success.","e2t":"Başarının görkeminin tadını çıkarmak (keyfini sürmek)."},{"w":"bastion","tr":"kale / burç / savunucu / dayanak","te":"Noun","tt":"İsim","de":"A projecting part of a fortification; or an institution or person defending particular principles","dt":"Bir tahkimatın çıkıntı yapan kısmı (burç); veya belirli ilkeleri savunan kurum ya da kişi","e1":"A bastion of democracy.","e1t":"Demokrasinin kalesi (son sığınağı).","e2":"The old bastion of the city walls.","e2t":"Şehir surlarının eski burcu."},{"w":"bate","tr":"azaltmak / dindirmek / tutmak (nefes)","te":"Verb","tt":"Fiil","de":"Restrain or moderate (the force or intensity of something)","dt":"(Bir şeyin gücünü veya şiddetini) dizginlemek veya hafifletmek","e1":"With bated breath (idiom: heyecanla/nefesini tutarak).","e1t":"Nefesini tutmuş bir halde.","e2":"","e2t":""},{"w":"bauble","tr":"ıvır zıvır / değersiz takı / süs","te":"Noun","tt":"Isim","de":"A small, showy trinket or decoration","dt":"Küçük, gösterişli ama değersiz süs eşyası veya takı","e1":"Christmas tree baubles.","e1t":"Noel ağacı süsleri.","e2":"To waste money on baubles.","e2t":"Ivır zıvıra para harcamak."},{"w":"bawdy","tr":"müstehcen / açık saçık (komik anlamda)","te":"Adjective","tt":"Sıfat","de":"Dealing with sexual matters in a comical way; indecorous","dt":"Cinsel konuları mizahi bir şekilde ele alan; açık saçık","e1":"Bawdy jokes.","e1t":"Müstehcen şakalar.","e2":"A bawdy song.","e2t":"Açık saçık bir şarkı."},{"w":"beatific","tr":"mutluluk saçan / kutsal","te":"Adjective","tt":"Sıfat","de":"Feeling or expressing blissful happiness","dt":"Mutluluk veren veya ifade eden","e1":"A beatific smile.","e1t":"Huzur dolu (mutluluk saçan) bir gülümseme.","e2":"Beatific vision.","e2t":"Kutsal vizyon."},{"w":"beatitude","tr":"saadet / mutluluk / kutsanmışlık","te":"Noun","tt":"İsim","de":"Supreme blessedness","dt":"Yüce saadet (mutluluk)","e1":"A state of beatitude.","e1t":"Kutsal bir mutluluk hali.","e2":"The Beatitudes (Bible).","e2t":"(İncil'de) Dağdaki Vaaz'ın bölümleri."},{"w":"bedizen","tr":"süslemek / donatmak (gösterişli şekilde)","te":"Verb","tt":"Fiil","de":"Dress up or decorate gaudily","dt":"Şatafatlı veya zevksizce süslemek","e1":"A room bedizened with gold leaf.","e1t":"Altın varaklarla süslenmiş bir oda.","e2":"To bedizen oneself.","e2t":"Süslenip püslenmek."},{"w":"bedlam","tr":"tımarhane / kargaşa / curcuna","te":"Noun","tt":"İsim","de":"A scene of uproar and confusion","dt":"Gürültü ve kargaşa sahnesi","e1":"It was absolute bedlam in the classroom.","e1t":"Sınıfta tam bir curcuna (kargaşa) vardı.","e2":"(Tarihi olarak Londra'daki bir akıl hastanesinin adıdır).","e2t":""},{"w":"bedraggle","tr":"çamura bulamak / sırılsıklam ve kirli yapmak","te":"Verb","tt":"Fiil","de":"Make (something) untidy, messy, or wet","dt":"(Bir şeyi) düzensiz, dağınık veya ıslak (pasaklı) hale getirmek","e1":"Bedraggled appearance.","e1t":"Sırılsıklam ve perişan görünüm.","e2":"His clothes were bedraggled with mud.","e2t":"Kıyafetleri çamura bulanmıştı."},{"w":"befuddle","tr":"sersemletmek / aklını karıştırmak","te":"Verb","tt":"Fiil","de":"Make (someone) unable to think clearly","dt":"Birinin net düşünmesini engellemek (kafasını karıştırmak)","e1":"The complex rules befuddled the players.","e1t":"Karmaşık kurallar oyuncuların kafasını karıştırdı.","e2":"Befuddled by alcohol.","e2t":"Alkolün etkisiyle sersemlemiş."},{"w":"beget","tr":"neden olmak / yol açmak / babası olmak","te":"Verb","tt":"Fiil","de":"(Typically of a man) bring (a child) into existence by the process of reproduction; or to give rise to","dt":"(Genellikle erkek için) çocuk sahibi olmak; veya bir şeye yol açmak","e1":"Violence begets violence.","e1t":"Şiddet şiddeti doğurur.","e2":"He begat three sons.","e2t":"Üç erkek çocuk sahibi oldu (babası oldu)."},{"w":"begrudge","tr":"kıskanmak / çok görmek / esirgemek","te":"Verb","tt":"Fiil","de":"Envy (someone) the possession or enjoyment of (something)","dt":"Birinin bir şeye sahip olmasını veya tadını çıkarmasını kıskanmak; bir şeyi vermeye/yapmaya isteksiz olmak","e1":"I don't begrudge him his success.","e1t":"Onun başarısını kıskanmıyorum (ona çok görmüyorum).","e2":"To begrudge the time spent.","e2t":"Harcanan zamanı esirgemek (yüksünmek)."},{"w":"behemoth","tr":"devasa yaratık / dev / çok büyük şey","te":"Noun","tt":"İsim","de":"A huge or monstrous creature; or something enormous","dt":"Devasa veya canavarsı yaratık; veya çok büyük olan şey","e1":"A corporate behemoth.","e1t":"Dev bir şirket.","e2":"The behemoth emerged from the depths.","e2t":"Devasa yaratık derinliklerden çıktı."},{"w":"beholden","tr":"minnettar / borçlu","te":"Adjective","tt":"Sıfat","de":"Owing thanks or having a duty to someone in return for help or a service","dt":"Bir yardıma karşılık birine teşekkür borçlu veya minnettar olma","e1":"I don't want to be beholden to anyone.","e1t":"Kimseye borçlu (minnettar) kalmak istemiyorum.","e2":"Much beholden to you for your help.","e2t":"Yardımlarınız için size çok minnettarım."},{"w":"behoove / behove","tr":"yakışmak / gereklemek /","te":"e düşmek","tt":"Verb","de":"Fiil","dt":"It is a duty or responsibility for someone to do something; it is appropriate","e1":"Birinin bir şeyi yapmasının görevi veya sorumluluğu olması; uygun düşmek","e1t":"It behooves us to consider all options.","e2":"Tüm seçenekleri değerlendirmek bize düşer (görevimizdir).","e2t":"It ill behooves you to criticize."},{"w":"belabor / belabour","tr":"gereksizce üzerinde durmak / dövmek / eleştirmek","te":"Verb","tt":"Fiil","de":"Argue or elaborate (a subject) in excessive detail; or to attack someone physically or verbally","dt":"Bir konuyu aşırı detaylandırarak (sakız gibi) uzatmak; veya birine fiziksel ya da sözlü saldırmak","e1":"There's no need to belabor the point.","e1t":"Bu noktayı daha fazla uzatmaya (üzerinde durmaya) gerek yok.","e2":"He belabored his opponent.","e2t":"Rakibini yerden yere vurdu (veya dövdü)."},{"w":"belated","tr":"gecikmiş / sonradan gelen","te":"Adjective","tt":"Sıfat","de":"Coming or happening later than should have been the case","dt":"Olması gerekenden daha geç gelen veya gerçekleşen","e1":"Belated birthday wishes.","e1t":"Gecikmiş doğum günü dilekleri.","e2":"A belated apology.","e2t":"Geç kalmış bir özür."},{"w":"beleaguer","tr":"kuşatmak / darlamak / sıkıntıya sokmak","te":"Verb","tt":"Fiil","de":"Lay siege to; or to beset with difficulties","dt":"Kuşatmak; veya zorluklarla çevrelemek (sıkıntıya sokmak)","e1":"The beleaguered city.","e1t":"Kuşatma altındaki şehir.","e2":"A beleaguered government.","e2t":"Sıkıntı içindeki (dört bir yanından saldırıya uğrayan) hükümet."},{"w":"belie","tr":"yalanlamak / gizlemek / çelişmek","te":"Verb","tt":"Fiil","de":"(Of an appearance) fail to give a true notion or impression of (something); disguise or contradict","dt":"(Görünüş için) bir şeyin gerçek niteliğini yansıtmamak; gizlemek veya çelişmek","e1":"His calm face belied his inner terror.","e1t":"Sakin yüzü içindeki dehşeti gizliyordu (yalanlıyordu).","e2":"The facts belie his claims.","e2t":"Gerçekler onun iddialarıyla çelişiyor."},{"w":"belittle","tr":"küçümsemek / hor görmek / aşağı görmek","te":"Verb","tt":"Fiil","de":"Make (someone or something) seem unimportant","dt":"Birini veya bir şeyi önemsizmiş gibi göstermek","e1":"Don't belittle her achievements.","e1t":"Onun başarılarını küçümseme.","e2":"He felt belittled by the comment.","e2t":"Yorum karşısında kendini aşağılanmış hissetti."},{"w":"bellicose","tr":"kavgacı / savaşçıl / saldırgan","te":"Adjective","tt":"Sıfat","de":"Demonstrating aggression and willingness to fight","dt":"Saldırganlık ve savaşma isteği gösteren","e1":"A bellicose statement from the ministry.","e1t":"Bakanlıktan gelen savaşçıl (sert) bir açıklama.","e2":"His bellicose attitude.","e2t":"Onun kavgacı tutumu."},{"w":"belligerent","tr":"kavgacı / saldırgan / savaşan (taraf)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Hostile and aggressive; or a nation or person engaged in war","dt":"Düşmanca ve saldırgan; veya savaş halindeki ulus/kişi","e1":"Belligerent behavior.","e1t":"Saldırgan davranış.","e2":"The belligerent nations.","e2t":"Savaşan devletler."},{"w":"bemused","tr":"şaşkın / hayrete düşmüş / aklı karışık","te":"Adjective","tt":"Sıfat","de":"Puzzled, confused, or bewildered","dt":"Şaşırmış, kafası karışmış","e1":"He had a bemused expression on his face.","e1t":"Yüzünde şaşkın bir ifade vardı.","e2":"She was bemused by the sudden change.","e2t":"Ani değişiklik karşısında şaşırıp kaldı."},{"w":"benediction","tr":"takdis / kutsama / hayır dua","te":"Noun","tt":"İsim","de":"The utterance or bestowing of a blessing, especially at the end of a religious service","dt":"Özellikle dini tören sonunda yapılan kutsama veya hayır dua","e1":"To pronounce a benediction.","e1t":"Kutsama duası okumak.","e2":"The priest raised his hands in benediction.","e2t":"Rahip ellerini kutsamak için kaldırdı."},{"w":"benefactor","tr":"hayırsever / bağışçı / iyilik yapan","te":"Noun","tt":"İsim","de":"A person who gives money or other help to a person or cause","dt":"Bir kişiye veya davaya para ya da başka yardımda bulunan kişi","e1":"A wealthy benefactor of the arts.","e1t":"Sanatın zengin bir bağışçısı.","e2":"He remains an anonymous benefactor.","e2t":"O, isimsiz bir hayırsever olarak kalıyor."},{"w":"beneficent","tr":"hayırsever / iyiliksever / faydalı","te":"Adjective","tt":"Sıfat","de":"(Of a person) generous or doing good; or resulting in good","dt":"(Kişi için) cömert veya iyilik yapan; veya iyi sonuçlanan","e1":"A beneficent ruler.","e1t":"İyiliksever bir hükümdar.","e2":"The beneficent effects of the new law.","e2t":"Yeni yasanın faydalı etkileri."},{"w":"beneficiary","tr":"hak sahibi / varis / lehtar","te":"Noun","tt":"İsim","de":"A person who derives advantage from something, especially a trust, will, or life insurance policy","dt":"Bir şeyden (özellikle miras veya sigortadan) fayda sağlayan kişi","e1":"The main beneficiary of the will.","e1t":"Mirasın ana varisi (lehtarı).","e2":"To be the beneficiary of someone's kindness.","e2t":"Birinin nezaketinden faydalanan kişi olmak."},{"w":"benign","tr":"iyi huylu / zararsız / nazik","te":"Adjective","tt":"Sıfat","de":"Gentle and kindly; or (of a disease) not harmful in effect","dt":"Nazik ve kibar; veya (hastalık için) zararsız (iyi huylu)","e1":"A benign tumor.","e1t":"İyi huylu (zararsız) tümör.","e2":"A benign old man.","e2t":"Müşfik (iyi kalpli) yaşlı bir adam."},{"w":"bequeath","tr":"miras bırakmak / vasiyet etmek","te":"Verb","tt":"Fiil","de":"Leave (a property) to a person or other beneficiary by a will","dt":"Bir mülkü vasiyet yoluyla birine bırakmak","e1":"He bequeathed his fortune to charity.","e1t":"Servetini hayır kurumuna miras bıraktı.","e2":"To bequeath a legacy of peace.","e2t":"Barış mirası bırakmak."},{"w":"bereave","tr":"yoksun bırakmak / sevdiğini kaybetmek (ölümle)","te":"Verb","tt":"Fiil","de":"Deprive someone of a loved one through a profound absence, especially due to death","dt":"Birini sevdiği birinden (özellikle ölüm yoluyla) yoksun bırakmak","e1":"The bereaved family.","e1t":"Yaslı (yakınını kaybetmiş) aile.","e2":"To be bereaved of one's parents.","e2t":"Ebeveynlerini kaybetmiş olmak."},{"w":"bereft","tr":"yoksun / mahrum / yalnız kalmış","te":"Adjective","tt":"Sıfat","de":"Deprived of or lacking something; or lonely and abandoned","dt":"Bir şeyden yoksun veya mahrum; veya yalnız ve terk edilmiş","e1":"Bereft of hope.","e1t":"Umutsuz (umuttan yoksun).","e2":"The room was bereft of furniture.","e2t":"Oda mobilyasızdı (eşyadan mahrumdu)."},{"w":"berserk","tr":"cinnet getirmiş / çılgına dönmüş / kontrolsüz","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Out of control with anger or excitement; wild or frenzied","dt":"Öfke veya heyecandan kontrolden çıkmış; vahşi","e1":"He went berserk and started throwing things.","e1t":"Çılgına döndü ve eşyaları fırlatmaya başladı.","e2":"To go berserk with joy.","e2t":"Sevinçten çılgına dönmek."},{"w":"beset","tr":"kuşatmak / sarmak / darlamak","te":"Verb","tt":"Fiil","de":"(Of a problem or difficulty) trouble or threaten persistently","dt":"(Sorun veya zorluk için) sürekli rahatsız etmek veya tehdit etmek","e1":"A project beset by difficulties.","e1t":"Zorluklarla dolu (kuşatılmış) bir proje.","e2":"Beset by doubts.","e2t":"Şüphelerle çevrili (şüpheler içinde)."},{"w":"besiege","tr":"kuşatmak / muhasara etmek / yağmuruna tutmak","te":"Verb","tt":"Fiil","de":"Surround (a place) with armed forces in order to capture it; or overwhelm with requests","dt":"Bir yeri ele geçirmek için etrafını sarmak; veya istek yağmuruna tutmak","e1":"The city was besieged for months.","e1t":"Şehir aylarca kuşatıldı.","e2":"To be besieged by fans.","e2t":"Hayranlar tarafından etrafı sarılmak."},{"w":"besmirch","tr":"lekelemek / kirletmek / (itibarına) zarar vermek","te":"Verb","tt":"Fiil","de":"Damage the reputation of (someone or something) in the opinion of others","dt":"Birinin veya bir şeyin itibarını başkalarının gözünde zedelemek","e1":"To besmirch someone's good name.","e1t":"Birinin iyi adına leke sürmek.","e2":"His reputation was besmirched by the scandal.","e2t":"İtibarı skandalla kirlendi."},{"w":"bestial","tr":"hayvanca / vahşi / gaddar","te":"Adjective","tt":"Sıfat","de":"Of or like an animal or animals; savagely cruel","dt":"Hayvan gibi; vahşice zalim","e1":"Bestial behavior.","e1t":"Hayvanca (vahşi) davranış.","e2":"Bestial cruelty.","e2t":"Vahşi gaddarlık."},{"w":"betoken","tr":"","te":"e işaret etmek /","tt":"in belirtisi olmak","de":"Verb","dt":"Fiil","e1":"Be a sign of; indicate","e1t":"Bir şeyin işareti veya belirtisi olmak","e2":"His silence betokened a lack of interest.","e2t":"Sessizliği ilgisizliğe işaret ediyordu."},{"w":"betroth","tr":"nişanlamak / söz kesmek","te":"Verb","tt":"Fiil","de":"Enter into a formal agreement to marry","dt":"Resmen evlenmek üzere sözleşmek","e1":"She was betrothed to a prince.","e1t":"Bir prensle nişanlıydı.","e2":"Betrothal (noun).","e2t":"Nişan / Söz kesme."},{"w":"bevy","tr":"grup / sürü / alay","te":"Noun","tt":"İsim","de":"A large group of people or things of a particular kind","dt":"Belirli bir türden büyük insan veya nesne grubu","e1":"A bevy of beautiful girls.","e1t":"Bir grup güzel kız.","e2":"A bevy of questions.","e2t":"Bir dizi (alay) soru."},{"w":"bewitch","tr":"büyülemek / efsunlamak / cezbetmek","te":"Verb","tt":"Fiil","de":"Cast a spell on and gain control over (someone) by magic; or enchant","dt":"Birine büyü yapmak; veya büyülemek (hayran bırakmak)","e1":"He was completely bewitched by her beauty.","e1t":"Onun güzelliği karşısında tamamen büyülenmişti.","e2":"Bewitching eyes.","e2t":"Büyüleyici gözler."},{"w":"biennial","tr":"iki yılda bir yapılan / iki yıllık (bitki)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Taking place every other year; or a plant that lives for two years","dt":"İki yılda bir gerçekleşen; veya iki yıl yaşayan bitki","e1":"A biennial art festival.","e1t":"İki yılda bir yapılan sanat festivali.","e2":"Biennial elections.","e2t":"İki yılda bir yapılan seçimler."},{"w":"bifurcated","tr":"ikiye ayrılmış / çatallı","te":"Adjective","tt":"Sıfat","de":"Divided into two branches or forks","dt":"İki dala veya çatala ayrılmış","e1":"A bifurcated road.","e1t":"İkiye ayrılan (çatallı) yol.","e2":"Bifurcated tongue.","e2t":"Çatallı dil."},{"w":"bigotry","tr":"bağnazlık / yobazlık / hoşgörüsüzlük","te":"Noun","tt":"İsim","de":"Intolerance towards those who hold different opinions","dt":"Farklı görüşlere sahip olanlara karşı hoşgörüsüzlük","e1":"Religious bigotry.","e1t":"Dini bağnazlık.","e2":"To fight against bigotry and prejudice.","e2t":"Bağnazlık ve önyargıya karşı savaşmak."},{"w":"bilious","tr":"hırçın / aksi / safravi / mide bulandırıcı","te":"Adjective","tt":"Sıfat","de":"Spiteful or bad","dt":"tempered; or relating to bile; or nauseous","e1":"Kinci veya kötü huylu; veya safra ile ilgili; veya mide bulandırıcı","e1t":"A bilious attack.","e2":"Safra (karaciğer) atağı / mide bulantısı.","e2t":"In a bilious mood."},{"w":"bilk","tr":"dolandırmak / atlatmak / (paranın) üstüne yatmak","te":"Verb","tt":"Fiil","de":"Obtain or withhold money from (someone) by deceit or without justification; cheat","dt":"Birini aldatarak parasını almak veya vermemek; dolandırmak","e1":"He bilked the investors out of millions.","e1t":"Yatırımcıları milyonlarca dolar dolandırdı.","e2":"To bilk someone of their earnings.","e2t":"Birinin kazancının üstüne yatmak."},{"w":"billow","tr":"dalgalanmak / kabarmak / büyük dalga","te":"Noun/Verb","tt":"İsim/Fiil","de":"A large undulating mass of something, typically cloud, smoke, or steam","dt":"Büyük, dalgalanan kütle (bulut, duman vb.); veya dalgalanmak","e1":"Smoke billowed from the chimney.","e1t":"Bacadan dumanlar yükseldi (dalga dalga çıktı).","e2":"The sails billowed in the wind.","e2t":"Yelkenler rüzgarda kabardı."},{"w":"bivouac","tr":"ordugah / açık havada gecelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A temporary camp without tents or cover, used especially by soldiers","dt":"Özellikle askerler tarafından kullanılan, çadırı olmayan geçici kamp","e1":"The troops set up a bivouac for the night.","e1t":"Birlikler gece için açık havada ordugah kurdu.","e2":"To bivouac under the stars.","e2t":"Yıldızların altında gecelemek."},{"w":"blanch","tr":"ağartmak / beyazlaşmak / şoklamak (sebze)","te":"Verb","tt":"Fiil","de":"Make white or pale by extracting color; or to whiten from fear; or to briefly boil food","dt":"Rengini alarak beyazlatmak; veya korkudan sararmak; veya gıdayı hafifçe haşlamak","e1":"He blanched with fear.","e1t":"Korkudan yüzü kireç gibi oldu (sarardı).","e2":"To blanch almonds.","e2t":"Bademleri (kabuğunu soymak için) haşlamak."},{"w":"bland","tr":"tatsız / yavan / yumuşak / nazik","te":"Adjective","tt":"Sıfat","de":"Lacking strong features or characteristics and therefore uninteresting","dt":"Güçlü özelliklerden yoksun ve bu nedenle ilginç olmayan","e1":"A bland diet.","e1t":"Tatsız tuzsuz (hafif) diyet.","e2":"Bland music.","e2t":"Yavan (sıkıcı) müzik."},{"w":"blare","tr":"yankılanmak / bağırmak / yüksek ve nahoş ses","te":"Verb/Noun","tt":"Fiil/İsim","de":"Make a wide as possible; or a loud and harsh sound","dt":"Çok yüksek ve nahoş bir ses çıkarmak","e1":"The radio was blaring out music.","e1t":"Radyo bangır bangır müzik çalıyordu.","e2":"The blare of trumpets.","e2t":"Trompetlerin sert sesi."},{"w":"blasé","tr":"kanıksamış / bıkkın / dünya yansa umrunda olmayan","te":"Adjective","tt":"Sıfat","de":"Unimpressed or indifferent to something because one has experienced it so often before","dt":"Daha önce çok kez deneyimlediği için bir şeye karşı ilgisiz veya etkilenmemiş","e1":"He has a blasé attitude towards luxury.","e1t":"Lükse karşı kanıksamış (ilgisiz) bir tavrı var.","e2":"To become blasé about travel.","e2t":"Seyahat etmekten bıkmak (heyecan duymamak)."},{"w":"blasphemy","tr":"küfür / kutsala saygısızlık / şirk","te":"Noun","tt":"İsim","de":"The act or offense of speaking sacrilegiously about God or sacred things","dt":"Tanrı veya kutsal şeyler hakkında saygısızca konuşma","e1":"He was accused of blasphemy.","e1t":"Kutsala saygısızlıkla (küfürle) suçlandı.","e2":"Blasphemous (adjective).","e2t":"Küfür niteliğinde / Saygısız."},{"w":"blatant","tr":"küstahça / bariz / apaçık (kötü bir şey için)","te":"Adjective","tt":"Sıfat","de":"(Of bad behavior) done openly and unashamedly","dt":"(Kötü davranış için) açıkça ve utanmazca yapılan","e1":"A blatant lie.","e1t":"Apaçık (bariz) bir yalan.","e2":"Blatant disregard for the rules.","e2t":"Kuralların küstahça çiğnenmesi."},{"w":"bliss","tr":"büyük mutluluk / saadet / huzur","te":"Noun","tt":"İsim","de":"Perfect happiness; great joy","dt":"Mükemmel mutluluk; büyük sevinç","e1":"Domestic bliss.","e1t":"Evlilik saadeti.","e2":"In a state of total bliss.","e2t":"Tam bir huzur/mutluluk içinde."},{"w":"blithe","tr":"neşeli / kaygısız / vurdumduymaz","te":"Adjective","tt":"Sıfat","de":"Showing a casual and cheerful indifference considered to be callous or improper","dt":"Neşeli ve (bazen uygunsuz derecede) kaygısız","e1":"A blithe disregard for danger.","e1t":"Tehlikeye karşı vurdumduymaz bir ilgisizlik.","e2":"Her blithe spirit.","e2t":"Onun neşeli ruhu."},{"w":"bloated","tr":"şişkin / kabarmış / gururlu","te":"Adjective","tt":"Sıfat","de":"Excessive in size or amount; or swollen with fluid or gas","dt":"Boyut veya miktar olarak aşırı; veya sıvı/gazla şişmiş","e1":"I feel bloated after that meal.","e1t":"O yemekten sonra kendimi şişmiş hissediyorum.","e2":"A bloated bureaucracy.","e2t":"Hantallaşmış (aşırı büyümüş) bürokrasi."},{"w":"bludgeon","tr":"sopa / sopayla dövmek / zorlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A thick stick with a heavy end, used as a weapon; or to bully or force someone","dt":"Silah olarak kullanılan ağır uçlu sopa; veya birini zorlamak/baskı kurmak","e1":"He was beaten with a bludgeon.","e1t":"Sopayla dövüldü.","e2":"To bludgeon someone into agreeing.","e2t":"Birini kabul etmesi için zorlamak (baskı yapmak)."},{"w":"bluff","tr":"blöf / kandırmaca / dik yamaç / kaba saba","te":"Noun/Verb/Adj","tt":"An attempt to deceive someone as to one's abilities or intentions; or a steep cliff","de":"Birini yetenekleri veya niyetleri hakkında aldatma girişimi; veya dik uçurum","dt":"He was just bluffing.","e1":"Sadece blöf yapıyordu.","e1t":"To call someone's bluff.","e2":"Birinin blöfünü görmek (meydan okumak).","e2t":""},{"w":"blurt","tr":"ağzından kaçırmak / birden söyleyivermek","te":"Verb","tt":"Fiil","de":"Say something suddenly and without careful consideration","dt":"Düşünmeden, aniden söyleyivermek","e1":"She blurted out the secret.","e1t":"Sırrı ağzından kaçırdı.","e2":"\"I love you!\" he blurted.","e2t":"\"Seni seviyorum!\" diye birden söyleyiverdi."},{"w":"bluster","tr":"gürlemek / esip savurmak / kabadayılık taslamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Talk in a loud, aggressive, or indignant way with little effect","dt":"Etkisi az, ancak yüksek sesli ve saldırgan bir şekilde konuşmak","e1":"\"I'll sue you!\" he blustered.","e1t":"\"Seni dava edeceğim!\" diye esti savurdu.","e2":"The bluster of the wind.","e2t":"Rüzgarın gürlemesi (sert esişi)."},{"w":"bode","tr":"","te":"e işaret etmek / habercisi olmak","tt":"Verb","de":"Fiil","dt":"Be an omen of a particular outcome","e1":"Belirli bir sonucun habercisi olmak","e1t":"This does not bode well for the future.","e2":"Bu, gelecek için hayra alamet değil.","e2t":"The quiet morning boded a peaceful day."},{"w":"bogus","tr":"sahte / düzmece / uydurma","te":"Adjective","tt":"Sıfat","de":"Not genuine or true; fake","dt":"Hakiki olmayan; sahte","e1":"A bogus insurance claim.","e1t":"Sahte bir sigorta talebi.","e2":"He was arrested for using a bogus passport.","e2t":"Sahte pasaport kullanmaktan tutuklandı."},{"w":"bohemian","tr":"bohem / kural tanımaz / göçebe ruhlu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who has informal and unconventional social habits","dt":"Alışılagelmişin dışında, kuralsız ve sanatsal bir yaşam süren kişi","e1":"A bohemian lifestyle.","e1t":"Bohem bir yaşam tarzı.","e2":"The city's bohemian district.","e2t":"Şehrin bohem (sanatçı) bölgesi."},{"w":"boisterous","tr":"gürültücü / taşkın / ele avuca sığmaz","te":"Adjective","tt":"Sıfat","de":"(Of a person, event, or behavior) noisy, energetic, and cheerful","dt":"(Kişi veya olay için) gürültülü, enerjik ve neşeli","e1":"A boisterous crowd of fans.","e1t":"Taşkın bir hayran kitlesi.","e2":"Boisterous children.","e2t":"Gürültücü (hareketli) çocuklar."},{"w":"bombastic","tr":"ağdalı / gösterişli ama boş (söz)","te":"Adjective","tt":"Sıfat","de":"High","dt":"sounding but with little meaning; inflated","e1":"Gösterişli tınlayan ancak anlamca boş; şişirilmiş","e1t":"A bombastic speech.","e2":"Ağdalı ve içi boş bir konuşma.","e2t":"His style of writing is rather bombastic."},{"w":"bonanza","tr":"zenginlik kaynağı / talih kuşu / bolluk","te":"Noun","tt":"İsim","de":"A situation which creates very sudden wealth or luck","dt":"Aniden büyük zenginlik veya şans getiren durum","e1":"A bonanza for local tourism.","e1t":"Yerel turizm için bir bolluk (zenginlik) kaynağı.","e2":"The film was a box","e2t":"office bonanza."},{"w":"bountiful","tr":"bol / bereketli / cömert","te":"Adjective","tt":"Sıfat","de":"Large in quantity; abundant; or giving generously","dt":"Miktar olarak çok; bereketli; veya cömertçe veren","e1":"A bountiful harvest.","e1t":"Bereketli bir hasat.","e2":"Our bountiful benefactor.","e2t":"Cömert hayırseverimiz."},{"w":"bourgeois","tr":"burjuva / orta sınıf / materyalist","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Belonging to or characteristic of the middle class","dt":"Orta sınıfa ait veya orta sınıf özelliklerini taşıyan","e1":"Bourgeois values.","e1t":"Burjuva (orta sınıf) değerleri.","e2":"A boring, bourgeois life.","e2t":"Sıkıcı, burjuva bir hayat."},{"w":"bovine","tr":"sığır gibi / hantal / uyuşuk","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to or affecting cattle; or dull and slow","dt":"Sığırlarla ilgili; veya donuk ve yavaş","e1":"Bovine growth hormone.","e1t":"Sığır büyüme hormonu.","e2":"A bovine expression on his face.","e2t":"Yüzünde uyuşuk (anlamsız) bir ifade."},{"w":"bowdlerize / bowdlerise","tr":"(kitap vb.) ayıklamak / sansürlemek","te":"Verb","tt":"Fiil","de":"Remove material that is considered improper or offensive","dt":"Müstehcen veya sakıncalı görülen kısımları çıkarmak (hafifletmek)","e1":"A bowdlerized version of the play.","e1t":"Oyunun sansürlenmiş (ayıklanmış) bir versiyonu.","e2":"To bowdlerize a text.","e2t":"Bir metni (sadeleştirme bahanesiyle) budamak."},{"w":"brackish","tr":"acı / tuzluca (su) / nahoş","te":"Adjective","tt":"Sıfat","de":"(Of water) slightly salty, as is the mixture of river water and seawater","dt":"(Su için) nehir ve deniz suyunun karışımı gibi hafif tuzlu ve acı","e1":"Brackish marshes.","e1t":"Acı su bataklıkları.","e2":"The tea tasted brackish.","e2t":"Çayın tadı nahoş (tuzlumsu) geliyordu."},{"w":"braggadocio","tr":"boş övünme / kabadayılık taslama","te":"Noun","tt":"İsim","de":"Boastful or arrogant behavior","dt":"Övüngen veya kibirli davranış","e1":"His speeches were full of braggadocio.","e1t":"Konuşmaları boş övünmelerle doluydu.","e2":"Behind all the braggadocio, he was very insecure.","e2t":"Tüm o kabadayılık taslamasının ardında aslında çok güvensiz biriydi."},{"w":"bravado","tr":"sahte cesaret / göz korkutma / caka","te":"Noun","tt":"İsim","de":"A bold manner or a show of boldness intended to impress or intimidate","dt":"Etkilemek veya göz korkutmak için yapılan cesaret gösterisi","e1":"A display of empty bravado.","e1t":"Kuru bir kabadayılık (cesaret) gösterisi.","e2":"He did it out of pure bravado.","e2t":"Bunu tamamen caka satmak (gösteriş) için yaptı."},{"w":"brawn","tr":"kas gücü / adale","te":"Noun","tt":"İsim","de":"Physical strength in contrast to intelligence","dt":"Zekanın aksine fiziksel güç","e1":"He has more brawn than brains.","e1t":"Kas gücü beyninden (zekasından) daha fazladır.","e2":"Brawny (adjective).","e2t":"Kaslı / Güçlü."},{"w":"brazen","tr":"küstah / utanmaz / pirinçten yapılmış","te":"Adjective","tt":"Sıfat","de":"Bold and without shame; or made of brass","dt":"Utanmaz ve küstah; veya pirinçten yapılmış","e1":"A brazen lie.","e1t":"Arsızca (utanmazca) bir yalan.","e2":"Her brazen disregard for the rules.","e2t":"Kuralları küstahça hiçe sayması."},{"w":"bridle","tr":"dizginlemek / öfkeyle diklenmek / yular","te":"Noun/Verb","tt":"İsim/Fiil","de":"To control or restrain; or to show resentment or anger","dt":"Kontrol etmek veya dizginlemek; veya içerlediğini/öfkelendiğini belli etmek","e1":"To bridle one's tongue.","e1t":"Dilini tutmak (dizginlemek).","e2":"She bridled at his suggestion.","e2t":"Onun önerisi karşısında öfkeyle diklendi (içerledi)."},{"w":"brim","tr":"kenar / ağzına kadar dolmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The upper edge or lip of a cup, bowl, or other container; or to be full to the point of overflowing","dt":"Bir kabın üst kenarı; veya taşacak kadar dolu olmak","e1":"The glass was filled to the brim.","e1t":"Bardak ağzına kadar doluydu.","e2":"Her eyes were brimming with tears.","e2t":"Gözleri yaşlarla dolup taşıyordu."},{"w":"brindled","tr":"kırçıl / benekli / çizgili (hayvan tüyü)","te":"Adjective","tt":"Sıfat","de":"(Of a domestic animal) brownish or tawny with streaks of other color","dt":"(Evcil hayvan için) kahverengimsi üzerine başka renk çizgili/benekli","e1":"A brindled cow.","e1t":"Kırçıl bir inek.","e2":"Brindled fur.","e2t":"Benekli/çizgili tüy."},{"w":"brink","tr":"eşik / kenar / uç","te":"Noun","tt":"İsim","de":"An extreme edge of land before a steep or vertical slope; or a point at which something is about to happen","dt":"Dik bir yamacın hemen öncesindeki kenar; veya bir şeyin gerçekleşmek üzere olduğu nokta","e1":"On the brink of disaster.","e1t":"Felaketin eşiğinde.","e2":"The brink of a cliff.","e2t":"Uçurumun kenarı."},{"w":"bristle","tr":"sert tüy / tüyleri diken diken olmak / öfkelenmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A short, stiff hair; or (of hair) to stand upright away from the skin; or to react angrily","dt":"Kısa ve sert tüy (fırça kılı); veya tüylerin dikilmesi; veya öfkelenmek","e1":"The bristles of a toothbrush.","e1t":"Diş fırçasının kılları.","e2":"He bristled at the insult.","e2t":"Hakaret karşısında tüyleri diken diken oldu (öfkelendi)."},{"w":"brocade","tr":"brokar / ağır ipekli kumaş / sim işlemeli kumaş","te":"Noun","tt":"İsim","de":"A rich fabric woven with a raised pattern, typically with gold or silver thread","dt":"Genellikle altın veya gümüş iplikle dokunmuş, kabartma desenli zengin kumaş","e1":"Curtains made of heavy brocade.","e1t":"Ağır brokardan yapılmış perdeler.","e2":"Brocade waistcoat.","e2t":"Sim işlemeli yelek."},{"w":"broil","tr":"ızgara yapmak / kavurmak / kavga","te":"Verb/Noun","tt":"Fiil/İsim","de":"Cook (meat or fish) by exposure to direct heat; or a noisy argument","dt":"(Et veya balığı) doğrudan ateşe tutarak pişirmek; veya gürültülü tartışma","e1":"Broiled chicken.","e1t":"Izgara tavuk.","e2":"The sun broiled the desert.","e2t":"Güneş çölü kavurdu."},{"w":"bromide","tr":"klişe / basmakalıp söz / yatıştırıcı","te":"Noun","tt":"Isim","de":"A trite and unoriginal idea or remark; or a compound used as a sedative","dt":"Basmakalıp ve orijinal olmayan fikir; veya yatıştırıcı olarak kullanılan bileşik","e1":"His speech was full of comforting bromides.","e1t":"Konuşması rahatlatıcı klişelerle doluydu.","e2":"Potassium bromide.","e2t":"Potasyum bromür."},{"w":"brooch","tr":"broş / iğne","te":"Noun","tt":"İsim","de":"An ornament fastened to clothing with a hinged pin and catch","dt":"Elbiseye iğne ile tutturulan süs eşyası","e1":"A silver brooch.","e1t":"Gümüş bir broş.","e2":"She pinned the brooch to her dress.","e2t":"Broşu elbisesine iğneledi."},{"w":"brood","tr":"kuluçkaya yatmak / düşünceye dalmak / yavrular","te":"Verb/Noun","tt":"Fiil/İsim","de":"Think deeply about something that makes one unhappy; or a family of young animals","dt":"Mutsuz eden bir şey hakkında derin derin düşünmek; veya bir hayvanın yavruları","e1":"To brood over a failure.","e1t":"Bir başarısızlık üzerine kara kara düşünmek (kuruntu yapmak).","e2":"A brood of chicks.","e2t":"Bir kümes civciv."},{"w":"brook","tr":"tahammül etmek / katlanmak / dere","te":"Verb/Noun","tt":"Fiil/İsim","de":"Tolerate or allow (something, typically dissent or opposition); or a small stream","dt":"(Genellikle muhalefete) müsaade etmek/katlanmak; veya küçük akarsu","e1":"He would brook no opposition.","e1t":"Hiçbir muhalefete tahammül etmezdi.","e2":"A babbling brook.","e2t":"Şırıl şırıl akan bir dere."},{"w":"browbeat","tr":"gözdağı vermek / yıldırmak / sindirmek","te":"Verb","tt":"Fiil","de":"Intimidate (someone), typically into doing something, with stern or abusive words","dt":"Sert veya kaba sözlerle birini (genellikle bir şey yapması için) korkutmak","e1":"To browbeat a witness.","e1t":"Bir tanığa gözdağı vermek.","e2":"Don't let them browbeat you into signing.","e2t":"İmzalaman için seni sindirmelerine izin verme."},{"w":"browse","tr":"göz gezdirmek / (hayvan) otlamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Survey goods or text in a leisurely way; or (of an animal) feed on leaves","dt":"Mallara veya metne şöyle bir bakmak; veya (hayvan için) yaprak/ot yemek","e1":"To browse through a book.","e1t":"Bir kitaba göz gezdirmek.","e2":"Just browsing, thank you.","e2t":"Sadece bakıyorum, teşekkürler."},{"w":"brunt","tr":"ana darbe / en ağır yük","te":"Noun","tt":"İsim","de":"The worst part or chief impact of a specified thing","dt":"Belirtilen bir şeyin en kötü kısmı veya ana etkisi","e1":"To bear the brunt of the attack.","e1t":"Saldırının en ağır yükünü (ana darbesini) göğüslemek.","e2":"Cities bear the brunt of the population explosion.","e2t":"Nüfus patlamasının asıl yükünü şehirler çeker."},{"w":"brusque","tr":"kaba / sert / kestirip atan","te":"Adjective","tt":"Sıfat","de":"Abrupt or offhand in speech or manner","dt":"Konuşmada veya tavırda ani ve nezaketsiz","e1":"A brusque reply.","e1t":"Sert ve kısa (kestirip atan) bir cevap.","e2":"He was brusque with the customers.","e2t":"Müşterilere karşı kaba (sert) davranıyordu."},{"w":"buccaneer","tr":"korsan / maceracı iş adamı","te":"Noun","tt":"İsim","de":"A pirate, originally one operating in the Caribbean; or an adventurous person","dt":"Korsan; veya maceracı (risk alan) kişi","e1":"Tales of Caribbean buccaneers.","e1t":"Karayip korsanlarının hikayeleri.","e2":"A corporate buccaneer.","e2t":"İş dünyasının maceracı (agresif) ismi."},{"w":"bucolic","tr":"kırsal / pastoral / köylü","te":"Adjective","tt":"Sıfat","de":"Relating to the pleasant aspects of the countryside and country life","dt":"Kır hayatının ve kırsalın hoş yanlarıyla ilgili","e1":"A bucolic scene.","e1t":"Huzurlu bir kırsal manzara.","e2":"They lead a bucolic life.","e2t":"Kırsal (doğal) bir hayat sürüyorlar."},{"w":"buffoon","tr":"soytarı / şaklaban / maskara","te":"Noun","tt":"İsim","de":"A ridiculous but amusing person; a clown","dt":"Komik ama gülünç kişi; palyaço","e1":"To act like a buffoon.","e1t":"Soytarı gibi davranmak.","e2":"Buffoonery (noun).","e2t":"Şaklabanlık."},{"w":"bugbear","tr":"korkulu rüya / öcü / nefret edilen şey","te":"Noun","tt":"İsim","de":"A cause of obsessive fear, irritation, or loathing","dt":"Takıntılı korku, rahatsızlık veya nefret nedeni","e1":"Spelling was always his bugbear.","e1t":"Yazım kuralları her zaman onun korkulu rüyasıydı.","e2":"The bugbear of inflation.","e2t":"Enflasyon belası (korkusu)."},{"w":"bullion","tr":"külçe (altın/gümüş)","te":"Noun","tt":"İsim","de":"Gold or silver in bulk before coining, or valued by weight","dt":"Madeni para basılmadan önceki veya ağırlığıyla değer biçilen külçe altın/gümüş","e1":"Gold bullion.","e1t":"Külçe altın.","e2":"Bullion reserves.","e2t":"Külçe rezervleri."},{"w":"bulwark","tr":"siper / istihkam / korunak / küpeşte","te":"Noun","tt":"İsim","de":"A defensive wall; or a person or thing that acts as a defense","dt":"Savunma duvarı; veya savunma görevi gören kişi/şey","e1":"A bulwark against invasion.","e1t":"İstilaya karşı bir siper (dayanak).","e2":"The bulwarks of a ship.","e2t":"Geminin küpeşteleri (bordasının üst kısmı)."},{"w":"bumptious","tr":"kendini beğenmiş / küstah / ukala","te":"Adjective","tt":"Sıfat","de":"Self","dt":"assertive or proud to an irritating degree","e1":"Sinir bozucu derecede kendini öne çıkaran veya gururlu","e1t":"A bumptious young man.","e2":"Kendini beğenmiş (ukala) bir genç.","e2t":"His bumptious manner."},{"w":"bungalow","tr":"bungalov / tek katlı ev","te":"Noun","tt":"İsim","de":"A low house having only one story","dt":"Tek katlı, alçak ev","e1":"We stayed in a seaside bungalow.","e1t":"Deniz kenarında bir bungalovda kaldık.","e2":"A detached bungalow.","e2t":"Müstakil tek katlı ev."},{"w":"bungle","tr":"eline yüzüne bulaştırmak / becerememek / pot kırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Carry out (a task) clumsily or incompetently","dt":"Bir işi beceriksizce veya sakarlıkla yapmak","e1":"They bungled the robbery.","e1t":"Soygunu ellerine yüzüne bulaştırdılar.","e2":"A serious administrative bungle.","e2t":"Ciddi bir yönetimsel hata (beceriksizlik)."},{"w":"burlesque","tr":"parodi / gülünç taklit / şakalı gösteri","te":"Noun/Verb","tt":"İsim/Fiil","de":"An absurd or comically exaggerated imitation of something","dt":"Bir şeyin saçma veya komik şekilde abartılmış taklidi","e1":"A burlesque of a Victorian novel.","e1t":"Victoria dönemi romanının gülünç bir parodisi.","e2":"To burlesque a serious subject.","e2t":"Ciddi bir konuyu alaya almak."},{"w":"burnish","tr":"parlatmak / cilalamak / (itibar) geliştirmek","te":"Verb","tt":"Fiil","de":"Polish (something, especially metal) by rubbing; or to enhance","dt":"(Özellikle metali) sürterek parlatmak; veya (imajı) güçlendirmek","e1":"To burnish the silver.","e1t":"Gümüşü parlatmak.","e2":"To burnish his public image.","e2t":"Halk arasındaki imajını cilalamak (iyileştirmek)."},{"w":"bursar","tr":"sayman / burs sorumlusu (üniversite)","te":"Noun","tt":"İsim","de":"A person who manages the financial affairs of a college or school","dt":"Bir kolej veya okulun mali işlerini yöneten kişi","e1":"The university bursar.","e1t":"Üniversite saymanı.","e2":"To pay fees to the bursar.","e2t":"Harçları saymana ödemek."},{"w":"buxom","tr":"dolgun vücutlu / gürbüz (kadın)","te":"Adjective","tt":"Sıfat","de":"(Of a woman) plump, healthy","dt":"looking, and full","e1":"bosomed","e1t":"(Kadın için) toplu, sağlıklı görünümlü ve dolgun","e2":"A buxom country girl.","e2t":"Gürbüz (sağlıklı ve dolgun) bir köylü kızı."},{"w":"cabal","tr":"klik / cunta / gizli grup","te":"Noun","tt":"İsim","de":"A secret political faction or maneuver","dt":"Gizli bir siyasi grup veya entrika","e1":"A cabal of advisors.","e1t":"Danışmanlardan oluşan gizli bir klik.","e2":"To be part of a cabal.","e2t":"Bir cuntanın (gizli grubun) parçası olmak."},{"w":"cache","tr":"önbellek / gizli depo / saklanan yer","te":"Noun/Verb","tt":"İsim/Fiil","de":"A hiding place, especially one in the ground; or to store away","dt":"Özellikle yer altında bulunan gizli depo; veya saklamak","e1":"A cache of weapons.","e1t":"Gizli silah deposu.","e2":"To cache data (computing).","e2t":"Veriyi önbelleğe almak."},{"w":"cacophony","tr":"kakofoni / ses uyumsuzluğu / gürültü","te":"Noun","tt":"İsim","de":"A harsh discordant mixture of sounds","dt":"Sert ve uyumsuz sesler topluluğu","e1":"A cacophony of car horns.","e1t":"Araba kornalarının oluşturduğu kakofoni (gürültü).","e2":"The cacophony in the school cafeteria.","e2t":"Okul yemekhanesindeki ses karmaşası."},{"w":"cadaver","tr":"kadavra / ceset","te":"Noun","tt":"İsim","de":"A corpse which is intended for dissection","dt":"Parçalanarak incelenmek (otopsi vb.) üzere ayrılmış ceset","e1":"Medical students studying a cadaver.","e1t":"Kadavra üzerinde çalışan tıp öğrencileri.","e2":"Cadaverous (adjective: ceset gibi solgun).","e2t":""},{"w":"cadence","tr":"kadans / ritim / ses düşümü","te":"Noun","tt":"İsim","de":"A modulation or inflection of the voice; or a rhythmic flow","dt":"Sesin tonlaması veya bükümü; veya ritmik akış","e1":"The slow cadence of his speech.","e1t":"Konuşmasının yavaş ritmi (tonlaması).","e2":"A final cadence in music.","e2t":"Müzikte bitiş kadansı."},{"w":"cajole","tr":"dil dökmek / kandırmak / tatlılıkla ikna etmek","te":"Verb","tt":"Fiil","de":"Persuade (someone) to do something by sustained coaxing or flattery","dt":"Birini ikna etmek için sürekli dil dökmek veya yağ çekmek","e1":"He cajoled her into signing the document.","e1t":"Onu belgeyi imzalaması için tatlı dille ikna etti.","e2":"Cajolement (noun).","e2t":"Dil dökme."},{"w":"calamity","tr":"afet / felaket / yıkım","te":"Noun","tt":"İsim","de":"An event causing great and often sudden damage or distress","dt":"Büyük ve genellikle ani hasar veya sıkıntıya neden olan olay","e1":"A natural calamity.","e1t":"Doğal afet.","e2":"The loss of his job was a financial calamity.","e2t":"İşini kaybetmesi finansal bir yıkımdı."},{"w":"caldron / cauldron","tr":"kazan / büyük tencere","te":"Noun","tt":"İsim","de":"A large metal pot with a lid and handle, used for cooking over an open fire","dt":"Açık ateş üzerinde yemek pişirmek için kullanılan büyük metal kap","e1":"A witch's cauldron.","e1t":"Cadı kazanı.","e2":"A cauldron of emotions.","e2t":"Duygu kazanı (karmaşası)."},{"w":"caliber / calibre","tr":"kalibre / çap / yetenek / kalite","te":"Noun","tt":"İsim","de":"The quality of someone's character or level of ability; or the diameter of a bullet","dt":"Birinin karakter kalitesi veya yetenek düzeyi; veya merminin çapı","e1":"We need a person of your caliber.","e1t":"Senin kalibrende (yetenek seviyende) birine ihtiyacımız var.","e2":"High","e2t":"caliber research."},{"w":"calligraphy","tr":"kaligrafi / hat sanatı","te":"Noun","tt":"İsim","de":"Decorative handwriting or handwritten lettering","dt":"Dekoratif el yazısı veya el yazması harf sanatı","e1":"Master of Arabic calligraphy.","e1t":"Arap hat sanatı ustası.","e2":"To practice calligraphy.","e2t":"Kaligrafi (güzel yazı) çalışmak."},{"w":"callous","tr":"duyarsız / katı yürekli / nasırlaşmış","te":"Adjective","tt":"Sıfat","de":"Showing or having an insensitive and cruel disregard for others","dt":"Başkalarına karşı duyarsız ve zalimce bir umursamazlık göstermek","e1":"A callous disregard for safety.","e1t":"Güvenliğe karşı duyarsız bir ilgisizlik.","e2":"He is a callous man.","e2t":"O katı yürekli (duygusuz) biridir."},{"w":"callow","tr":"toy / deneyimsiz / acemi","te":"Adjective","tt":"Sıfat","de":"(Of a young person) inexperienced and immature","dt":"(Genç için) deneyimsiz ve olgunlaşmamış","e1":"A callow youth.","e1t":"Toy (tecrübesiz) bir delikanlı.","e2":"His callow remarks.","e2t":"Onun çocukça (deneyimsizce) yorumları."},{"w":"calorific","tr":"kalori ile ilgili / ısı veren","te":"Adjective","tt":"Sıfat","de":"Relating to the amount of energy food or fuel can produce","dt":"Gıda veya yakıtın üretebileceği enerji miktarı ile ilgili","e1":"The calorific value of coal.","e1t":"Kömürün kalori (ısı) değeri.","e2":"High calorific intake.","e2t":"Yüksek kalori alımı."},{"w":"calumny","tr":"iftira / karalama","te":"Noun","tt":"İsim","de":"The making of false and defamatory statements about someone in order to damage their reputation","dt":"Birinin itibarını sarsmak için hakkında yapılan asılsız ve küçültücü beyan","e1":"To spread calumnies about a rival.","e1t":"Bir rakip hakkında iftiralar yaymak.","e2":"Calumnious (adjective).","e2t":"İftira niteliğinde."},{"w":"camaraderie","tr":"yoldaşlık / arkadaşlık / dostluk","te":"Noun","tt":"İsim","de":"Mutual trust and friendship among people who spend a lot of time together","dt":"Birlikte çok zaman geçiren insanlar arasındaki karşılıklı güven ve dostluk","e1":"The camaraderie among the soldiers.","e1t":"Askerler arasındaki yoldaşlık.","e2":"A sense of camaraderie.","e2t":"Dostluk duygusu."},{"w":"cameo","tr":"kısa rol / minyatür işleme / kabartma mücevher","te":"Noun","tt":"İsim","de":"A small character part in a play or movie played by a distinguished actor; or a piece of jewelry","dt":"Ünlü bir oyuncu tarafından oynanan kısa rol; veya kabartmalı takı","e1":"He made a cameo appearance in the film.","e1t":"Filmde kısa bir rolde (konuk oyuncu olarak) göründü.","e2":"A shell cameo.","e2t":"Kabuktan yapılmış kabartma süs (broş)."},{"w":"canard","tr":"uydurma haber / yalan / asılsız söylenti","te":"Noun","tt":"İsim","de":"An unfounded rumor or story","dt":"Temelsiz söylenti veya hikaye","e1":"The old canard that the world is flat.","e1t":"Dünyanın düz olduğu yönündeki o eski uydurma.","e2":"To spread a malicious canard.","e2t":"Kötü niyetli bir yalan yaymak."},{"w":"canker","tr":"yara / kanser gibi yayılan kötülük / bitki yarası","te":"Noun/Verb","tt":"İsim/Fiil","de":"A destructive fungal disease of apple and other trees; or a corrupting influence","dt":"Elma ve diğer ağaçlarda görülen yıkıcı mantar hastalığı; veya yozlaştırıcı etki","e1":"A canker of jealousy.","e1t":"Kıskançlık yarası (kötülüğü).","e2":"The canker of corruption.","e2t":"Yolsuzluk illeti (yarası)."},{"w":"canny","tr":"kurnaz / uyanık / tedbirli","te":"Adjective","tt":"Sıfat","de":"Having or showing shrewdness and good judgment, especially in money or business","dt":"Özellikle para veya iş konularında kurnazlık ve iyi muhakeme gösteren","e1":"A canny investment.","e1t":"Akıllıca (uyanıkça) bir yatırım.","e2":"He is a canny politician.","e2t":"Kurnaz bir siyasetçidir."},{"w":"canon","tr":"kural / ilke / dini kanun / seçkin eserler listesi","te":"Noun","tt":"İsim","de":"A general law, rule, principle, or criterion by which something is judged; or a list of sacred books","dt":"Genel yasa, kural veya ilke; veya kutsal kitaplar/seçkin eserler listesi","e1":"The canons of good taste.","e1t":"İyi zevkin kuralları (ölçütleri).","e2":"Canon law (church).","e2t":"Kilise hukuku."},{"w":"cant","tr":"riyakarlık / ağız / eğim / yan yatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Hypocritical and sanctimonious talk; or the specialized language of a group; or a slope","dt":"Riyakar ve kutsallık taslayan konuşma; veya bir grubun jargonu; veya eğim","e1":"Political cant.","e1t":"Siyasi riyakarlık (boş laf).","e2":"Thieves' cant.","e2t":"Hırsızların argosu."},{"w":"cantankerous","tr":"huysuz / aksi / geçimsiz","te":"Adjective","tt":"Sıfat","de":"Bad","dt":"tempered, argumentative, and uncooperative","e1":"Kötü huylu, tartışmacı ve uyumsuz","e1t":"A cantankerous old man.","e2":"Huysuz (aksi) bir ihtiyar.","e2t":"Why are you so cantankerous today?"},{"w":"cantata","tr":"kantat","te":"Noun","tt":"İsim","de":"A medium","dt":"length narrative piece of music for voices with instrumental accompaniment","e1":"Enstrüman eşliğinde sesler için bestelenmiş, orta uzunlukta müzik parçası","e1t":"A Bach cantata.","e2":"Bir Bach kantatı.","e2t":"Secular cantata."},{"w":"canter","tr":"rahvan gidiş / yarım dört nala","te":"Noun/Verb","tt":"İsim/Fiil","de":"A three","dt":"beat gait of a horse or other quadruped between a trot and a gallop","e1":"Atın tırıs ile dört nala arasındaki üç zamanlı yürüyüşü","e1t":"To ride at a gentle canter.","e2":"Rahvan (hafif tempolu) gitmek.","e2t":"The horse cantered across the field."},{"w":"canto","tr":"kanto / bölüm (şiirde)","te":"Noun","tt":"Isim","de":"One of the sections into which certain long poems are divided","dt":"Uzun bir şiirin bölümlerinden her biri","e1":"The first canto of the epic.","e1t":"Destanın ilk kantosu (bölümü).","e2":"Dante's Cantos.","e2t":"Dante'nin bölümleri."},{"w":"canvass","tr":"kamuoyu yoklaması yapmak / oy istemek / incelemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Solicit votes from (electors in a constituency); or to examine in detail","dt":"(Seçmenlerden) oy istemek; veya detaylıca incelemek","e1":"To canvass for the Liberal party.","e1t":"Liberal parti için oy toplamak (çalışma yapmak).","e2":"They canvassed the neighborhood.","e2t":"Mahalleyi kapı kapı dolaşıp fikir sordular."},{"w":"capillary","tr":"kılcal damar / kılcal","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Any of the fine branching blood vessels that form a network; or relating to a tube with a very small diameter","dt":"Bir ağ oluşturan ince kan damarları; veya çok küçük çaplı boruyla ilgili","e1":"Capillary action (physics).","e1t":"Kılcallık etkisi.","e2":"Blood capillaries.","e2t":"Kan kılcalları."},{"w":"caprice","tr":"kapris / maymun iştahlılık / ani istek","te":"Noun","tt":"İsim","de":"A sudden and unaccountable change of mood or behavior","dt":"Ruh hali veya davranıştaki ani ve açıklanamayan değişiklik","e1":"Driven by caprice rather than reason.","e1t":"Mantıktan ziyade anlık isteklerle (kaprislerle) hareket eden.","e2":"The caprices of the weather.","e2t":"Havanın değişkenlikleri (kararsızlığı)."},{"w":"caption","tr":"başlık / resim altı yazısı / altyazı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A title or brief explanation accompanying an illustration; or subtitles","dt":"Bir illüstrasyona eşlik eden başlık veya kısa açıklama; veya altyazı","e1":"Look at the caption under the photo.","e1t":"Fotoğrafın altındaki yazıya bak.","e2":"Closed captions (for the hearing impaired).","e2t":"(İşitme engelliler için) altyazılar."},{"w":"captious","tr":"kusur bulan / eleştirel / yanıltıcı","te":"Adjective","tt":"Sıfat","de":"Tending to find fault or raise petty objections","dt":"Kusur bulmaya veya küçük itirazlar yükseltmeye meyilli","e1":"A captious critic.","e1t":"Kusur arayan (zor beğenen) eleştirmen.","e2":"Captious questions.","e2t":"Yanıltıcı (açık arayan) sorular."},{"w":"captivate","tr":"büyülemek / cezbetmek / esir etmek","te":"Verb","tt":"Fiil","de":"Attract and hold the interest and attention of; charm","dt":"İlgi ve dikkati çekmek ve tutmak; büyülemek","e1":"He was captivated by her beauty.","e1t":"Onun güzelliğiyle büyülenmişti.","e2":"A captivating story.","e2t":"Sürükleyici (cezbedici) bir hikaye."},{"w":"carat","tr":"karat (mücevher ağırlık birimi)","te":"Noun","tt":"İsim","de":"A unit of weight for precious stones and pearls","dt":"Değerli taşlar ve inciler için ağırlık birimi","e1":"A two","e1t":"carat diamond.","e2":"İki karatlık elmas. (Not: Altın saflığı için 'karat' ABD'de 'Karat', İngiltere'de 'Carat' olarak kullanılır ancak bazen farklı yazılır: Karat vs Carat).","e2t":""},{"w":"carcinogenic","tr":"kanserojen / kanser yapıcı","te":"Adjective","tt":"Sıfat","de":"Having the potential to cause cancer","dt":"Kanser yapma potansiyeli olan","e1":"Carcinogenic chemicals in tobacco.","e1t":"Tütündeki kanserojen kimyasallar.","e2":"Carcinogen (noun).","e2t":"Kanserojen madde."},{"w":"cardiologist","tr":"kardiyolog / kalp doktoru","te":"Noun","tt":"İsim","de":"A doctor who specializes in the study or treatment of heart diseases","dt":"Kalp hastalıkları üzerine uzmanlaşmış doktor","e1":"He was referred to a cardiologist for chest pains.","e1t":"Göğüs ağrıları nedeniyle bir kardiyoloğa sevk edildi.","e2":"Cardiology (noun).","e2t":"Kardiyoloji."},{"w":"careen","tr":"yan yatmak / kontrolsüzce savrulmak","te":"Verb","tt":"Fiil","de":"To tilt to one side; or to move swiftly and in an uncontrolled way","dt":"Bir yana yatmak; veya kontrolsüzce ve hızla ilerlemek","e1":"The car careened around the corner.","e1t":"Araba köşeyi dönerken savruldu.","e2":"To careen a ship (for cleaning).","e2t":"Bir gemiyi (temizlik için) yan yatırmak."},{"w":"carillon","tr":"karilyon / çan takımı","te":"Noun","tt":"İsim","de":"A set of bells hung in a tower and played by a keyboard","dt":"Bir kuleye asılmış ve klavye ile çalınan çan takımı","e1":"The carillon played a traditional melody.","e1t":"Çan takımı geleneksel bir melodi çaldı.","e2":"The sound of the carillon at noon.","e2t":"Öğle vaktindeki karilyon sesi."},{"w":"carnage","tr":"katliam / kıyım / kan gölü","te":"Noun","tt":"İsim","de":"The killing of a large number of people","dt":"Çok sayıda insanın öldürülmesi (vahşet)","e1":"The carnage of the battlefield.","e1t":"Savaş alanındaki katliam.","e2":"To prevent further carnage.","e2t":"Daha fazla kıyımı önlemek."},{"w":"carnal","tr":"bedensel / şehvetli / dünyevi","te":"Adjective","tt":"Sıfat","de":"Relating to physical, especially sexual, needs and activities","dt":"Fiziksel, özellikle cinsel ihtiyaç ve faaliyetlerle ilgili","e1":"Carnal desires.","e1t":"Şehvetli (bedensel) arzular.","e2":"Carnal knowledge (legal term for sexual intercourse).","e2t":"Cinsel ilişki."},{"w":"carousal","tr":"alem / cümbüş / içkili eğlence","te":"Noun","tt":"İsim","de":"A noisy, drunken gathering","dt":"Gürültülü ve içkili toplu eğlence","e1":"A night of wild carousal.","e1t":"Taşkın bir eğlence gecesi. (Not: 'Carousel'","e2":"atlıkarınca","e2t":"ile karıştırılmamalıdır)."},{"w":"carping","tr":"kusur bulan / dırdırcı / müşkülpesent","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Difficult to please; critical","dt":"Memnun etmesi zor; sürekli kusur bulan","e1":"To grow tired of his constant carping.","e1t":"Onun sürekli dırdırından (eleştirisinden) bıkmak.","e2":"Carping criticism.","e2t":"Yersiz (küçük şeylere takılan) eleştiri."},{"w":"carrion","tr":"leş / karkas","te":"Noun","tt":"İsim","de":"The decaying flesh of dead animals","dt":"Ölü hayvanların çürümekte olan eti","e1":"Vultures feed on carrion.","e1t":"Akbabalar leşle beslenir.","e2":"The smell of rotting carrion.","e2t":"Çürüyen leş kokusu."},{"w":"cartography","tr":"haritacılık / kartografya","te":"Noun","tt":"İsim","de":"The science or practice of drawing maps","dt":"Harita çizme bilimi veya pratiği","e1":"Modern cartography uses satellite images.","e1t":"Modern haritacılık uydu görüntülerini kullanır.","e2":"Cartographer (noun).","e2t":"Haritacı."},{"w":"caste","tr":"kast / toplumsal sınıf","te":"Noun","tt":"İsim","de":"Each of the hereditary classes of Hindu society; or a social class","dt":"Hindu toplumundaki babadan oğula geçen sınıfların her biri; veya toplumsal sınıf","e1":"The caste system in India.","e1t":"Hindistan'daki kast sistemi.","e2":"To lose caste (lose social status).","e2t":"Toplumsal statüsünü kaybetmek."},{"w":"casuistry","tr":"safsata / yanıltıcı mantık / kazuistik","te":"Noun","tt":"Isim","de":"The use of clever but unsound reasoning, especially in relation to moral questions","dt":"Özellikle ahlaki sorularda kullanılan zekice ama temelsiz akıl yürütme (kelime oyunu)","e1":"That's just a piece of casuistry!","e1t":"Bu sadece bir safsata!","e2":"To be misled by political casuistry.","e2t":"Siyasi kelime oyunlarıyla (safsatayla) kandırılmak."},{"w":"cataclysm","tr":"kataklizma / büyük felaket / altüst oluş","te":"Noun","tt":"Isim","de":"A sudden violent social or political upheaval; or a large","dt":"scale disaster","e1":"Ani ve şiddetli toplumsal/siyasi altüst oluş; veya büyük çaplı felaket","e1t":"The cataclysm of the French Revolution.","e2":"Fransız Devrimi'nin büyük altüst oluşu.","e2t":"A global cataclysm."},{"w":"catapult","tr":"mancınık / sapan / fırlatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A device in which accumulated tension is suddenly released to hurl an object; or to hurl or launch","dt":"Nesneleri fırlatmak için kullanılan düzenek; veya fırlatmak","e1":"The success of the film catapulted him to fame.","e1t":"Filmin başarısı onu bir anda şöhrete fırlattı (taşıdı).","e2":"A medieval catapult.","e2t":"Orta Çağ mancınığı."},{"w":"cataract","tr":"katarakt / büyük şelale","te":"Noun","tt":"İsim","de":"A medical condition in which the lens of the eye becomes progressively opaque, resulting in blurred vision; or a large waterfall","dt":"Göz merceğinin saydamlığını yitirmesi (katarakt); veya büyük şelale","e1":"He had an operation to remove a cataract.","e1t":"Kataraktını aldırmak için ameliyat oldu.","e2":"The cataracts of the Nile.","e2t":"Nil'in büyük çağlayanları."},{"w":"catcall","tr":"yuhalamak / ıslıklamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shrill whistle or shout of disapproval made at a public meeting or performance","dt":"Toplu bir toplantı veya gösteride yapılan onaylamama ıslığı veya bağırtısı","e1":"The speaker was greeted with catcalls.","e1t":"Konuşmacı yuhalamalarla karşılandı.","e2":"To catcall a performer.","e2t":"Bir göstericiyi ıslıklamak."},{"w":"categorical / categoric","tr":"kesin / koşulsuz / kategorik","te":"Adjective","tt":"Sıfat","de":"Unambiguously explicit and direct","dt":"Net bir şekilde açık ve doğrudan (şüpheye yer bırakmayan)","e1":"A categorical denial.","e1t":"Kesin bir ret (yalanlama).","e2":"To give a categorical answer.","e2t":"Net (kesin) bir cevap vermek."},{"w":"catharsis","tr":"katarsis / duygusal boşalım / arınma","te":"Noun","tt":"İsim","de":"The process of releasing, and thereby providing relief from, strong or repressed emotions","dt":"Güçlü veya bastırılmış duyguların serbest bırakılması ve böylece rahatlama sağlanması süreci","e1":"Writing the book was a form of catharsis for her.","e1t":"Kitabı yazmak onun için bir tür arınma (duygusal boşalım) oldu.","e2":"Cathartic (adjective).","e2t":"Arındırıcı / Rahatlatıcı."},{"w":"catholic","tr":"evrensel / geniş kapsamlı / katolik","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Including a wide variety of things; all","dt":"embracing; or relating to the Roman Catholic Church","e1":"Çok çeşitli şeyleri içeren (evrensel); veya Katolik kilisesi ile ilgili","e1t":"He has catholic tastes in music.","e2":"Müzikte çok geniş (evrensel) zevkleri vardır.","e2t":"The Catholic Church."},{"w":"caucus","tr":"parti meclisi / kapalı grup toplantısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A meeting of the senior members of a political party to decide policy or candidates","dt":"Bir siyasi partinin politika veya aday belirlemek için yaptığı kapalı toplantı","e1":"The Republican caucus.","e1t":"Cumhuriyetçilerin grup toplantısı.","e2":"To caucus for a candidate.","e2t":"Bir aday için grup toplantısı yapmak."},{"w":"cauterize / cauterise","tr":"dağlamak / (yarayı) yakarak kapatmak","te":"Verb","tt":"Fiil","de":"Burn the skin or flesh of (a wound) with a heated instrument or caustic substance, typically to stop bleeding","dt":"Kanamayı durdurmak için yarayı ısıtılmış bir alet veya yakıcı madde ile yakmak","e1":"The doctor had to cauterize the wound.","e1t":"Doktor yarayı dağlamak zorunda kaldı.","e2":"Cauterization (noun).","e2t":"Dağlama."},{"w":"cavalcade","tr":"atlı alay / kortej / geçit töreni","te":"Noun","tt":"İsim","de":"A formal procession of people walking, on horseback, or riding in vehicles","dt":"Yürüyen, at binen veya araçtaki insanların oluşturduğu resmi geçit","e1":"A cavalcade of black limousines.","e1t":"Siyah limuzinlerden oluşan bir kortej.","e2":"To watch the royal cavalcade.","e2t":"Kraliyet geçit törenini izlemek."},{"w":"cavalier","tr":"küstah / umursamaz / şövalye / süvari","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Showing a lack of proper concern; offhand; or a courtly gentleman","dt":"Gereken özeni göstermeyen (umursamaz); veya kibar beyefendi/süvari","e1":"A cavalier attitude towards the law.","e1t":"Yasaya karşı umursamaz (küstahça) bir tavır.","e2":"Royalist cavaliers.","e2t":"Kralcı süvariler."},{"w":"cavil","tr":"kusur bulmak / önemsiz şeylere itiraz etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Make petty or unnecessary objections","dt":"Küçük veya gereksiz itirazlarda bulunmak","e1":"I don't want to cavil about the price.","e1t":"Fiyat hakkında küçük hesaplar peşinde koşmak (itiraz etmek) istemiyorum.","e2":"Cavilling (adjective).","e2t":"Kusur bulan."},{"w":"cede","tr":"feragat etmek / (toprak vb.) bırakmak / devretmek","te":"Verb","tt":"Fiil","de":"Give up (power or territory)","dt":"(Güç veya toprak) bırakmak/devretmek","e1":"Spain ceded the territory to the US.","e1t":"İspanya bölgeyi ABD'ye devretti.","e2":"To cede control.","e2t":"Kontrolü bırakmak."},{"w":"celebrated","tr":"ünlü / meşhur / saygın","te":"Adjective","tt":"Sıfat","de":"Famous and respected","dt":"Meşhur ve saygı duyulan","e1":"A celebrated artist.","e1t":"Ünlü bir sanatçı.","e2":"A celebrated legal case.","e2t":"Meşhur bir dava."},{"w":"celerity","tr":"hız / sürat / çeviklik","te":"Noun","tt":"İsim","de":"Swiftness of movement (formal)","dt":"Hareket hızı (resmi)","e1":"To act with celerity.","e1t":"Süratle hareket etmek.","e2":"The celerity of the response.","e2t":"Yanıtın hızı."},{"w":"celibate","tr":"bekar (dini nedenlerle) / iffetli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Abstaining from marriage and sexual relations, typically for religious reasons","dt":"Genellikle dini nedenlerle evlilikten ve cinsel ilişkiden kaçınan","e1":"Catholic priests remain celibate.","e1t":"Katolik rahipler bekar (iffetli) kalırlar.","e2":"To lead a celibate life.","e2t":"İffetli bir hayat sürmek."},{"w":"censorious","tr":"çok eleştirel / kusur bulan / kınayan","te":"Adjective","tt":"Sıfat","de":"Severely critical of others","dt":"Başkalarına karşı çok eleştirel olan","e1":"A censorious attitude.","e1t":"Eleştirel (kınayan) bir tavır.","e2":"His censorious remarks.","e2t":"Onun kusur bulan yorumları."},{"w":"centaur","tr":"santor / at adam (mitoloji)","te":"Noun","tt":"İsim","de":"A creature with the upper body of a human and the lower body and legs of a horse","dt":"Belden yukarısı insan, aşağısı at olan mitolojik yaratık","e1":"Stories of centaurs in Greek mythology.","e1t":"Yunan mitolojisindeki santor hikayeleri.","e2":"","e2t":""},{"w":"centigrade","tr":"santigrat","te":"Adjective","tt":"Sıfat","de":"Relating to a scale of temperature on which water freezes at 0° and boils at 100°","dt":"Suyun 0°'de donduğu ve 100°'de kaynadığı sıcaklık ölçeği ile ilgili","e1":"20 degrees centigrade.","e1t":"20 santigrat derece. (Not: Günümüzde daha çok 'Celsius' tercih edilir).","e2":"","e2t":""},{"w":"centrifugal","tr":"merkezkaç","te":"Adjective","tt":"Sıfat","de":"Moving or tending to move away from a center","dt":"Merkezden uzaklaşan veya uzaklaşma eğiliminde olan","e1":"Centrifugal force.","e1t":"Merkezkaç kuvveti.","e2":"A centrifugal pump.","e2t":"Merkezkaç pompa."},{"w":"centripetal","tr":"merkezcil","te":"Adjective","tt":"Sıfat","de":"Moving or tending to move towards a center","dt":"Merkeze doğru hareket eden veya etme eğiliminde olan","e1":"Centripetal force.","e1t":"Merkezcil kuvvet.","e2":"Centripetal acceleration.","e2t":"Merkezcil ivme."},{"w":"centurion","tr":"santurio / yüzbaşı (Eski Roma)","te":"Noun","tt":"İsim","de":"The commander of a century (a group of 100 soldiers) in the ancient Roman army","dt":"Eski Roma ordusunda bir bölüğün (100 asker) komutanı","e1":"A Roman centurion.","e1t":"Romalı bir yüzbaşı.","e2":"","e2t":""},{"w":"cerebral","tr":"beyinsel / zihinsel / entelektüel","te":"Adjective","tt":"Sıfat","de":"Relating to the brain; or intellectual rather than emotional","dt":"Beyinle ilgili; veya duygusaldan ziyade zihinsel (entelektüel)","e1":"Cerebral cortex.","e1t":"Beyin kabuğu (korteks).","e2":"Cerebral hemorrhage.","e2t":"Beyin kanaması."},{"w":"cerebration","tr":"zihinsel faaliyet / düşünme","te":"Noun","tt":"İsim","de":"The working of the brain; thinking","dt":"Beynin çalışması; düşünme eylemi","e1":"Deep cerebration.","e1t":"Derin düşünce (zihinsel çalışma).","e2":"The process of cerebration.","e2t":"Düşünme süreci."},{"w":"ceremonious","tr":"resmi / törensel / çok nazik","te":"Adjective","tt":"Sıfat","de":"Relating to or used for formal events of a religious or public nature; or excessively polite","dt":"Resmi törenlerle ilgili; veya aşırı (resmi) nazik","e1":"A ceremonious greeting.","e1t":"Çok resmi (törensel) bir karşılama.","e2":"To be ceremonious with guests.","e2t":"Misafirlere karşı aşırı resmi (nazik) davranmak."},{"w":"certitude","tr":"kesinlik / emin olma","te":"Noun","tt":"İsim","de":"Absolute certainty or conviction that something is the case","dt":"Bir durumun öyle olduğuna dair tam emin olma veya inanç","e1":"I can say with certitude that...","e1t":"Kesinlikle söyleyebilirim ki...","e2":"Moral certitude.","e2t":"Ahlaki kesinlik."},{"w":"cessation","tr":"durma / kesilme / ara verme","te":"Noun","tt":"İsim","de":"The fact or process of ending or being brought to an end","dt":"Sona erme veya durdurulma süreci","e1":"The cessation of hostilities.","e1t":"Çatışmaların (düşmanlıkların) durması.","e2":"A cessation of smoking.","e2t":"Sigarayı bırakma (kesme)."},{"w":"cession","tr":"feragat / devir (toprak vb.)","te":"Noun","tt":"İsim","de":"The formal giving up of rights, property, or territory by a state","dt":"Hakların, mülkiyetin veya toprağın bir devlet tarafından resmen bırakılması","e1":"The cession of Hong Kong to China.","e1t":"Hong Kong'un Çin'e devri.","e2":"A treaty of cession.","e2t":"Devir (feragat) antlaşması."},{"w":"chafe","tr":"sürtünerek aşındırmak / tahriş etmek / sabırsızlanmak","te":"Verb","tt":"Fiil","de":"To make sore by rubbing against it; or to become annoyed/impatient","dt":"Sürtünerek tahriş etmek; veya (kısıtlamalardan dolayı) öfkelenmek/sabırsızlanmak","e1":"The collar chafed his neck.","e1t":"Yaka boynunu tahriş etti.","e2":"To chafe at the delay.","e2t":"Gecikmeden dolayı sabırsızlanmak (öfkelenmek)."},{"w":"chaff","tr":"saman / değersiz şey / alay etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The husks of corn or other seed separated by winnowing or threshing; or worthless things; or to tease","dt":"Harman sırasında ayrılan tahıl kabukları (saman); veya değersiz şeyler; veya şaka yapmak","e1":"To separate the wheat from the chaff.","e1t":"Buğdayı samandan ayırmak (iyiyi kötüden ayırmak).","e2":"He chaffed her about her new hat.","e2t":"Yeni şapkasıyla ilgili onunla şakalaştı (takıldı)."},{"w":"chalice","tr":"kadeh (dini)","te":"Noun","tt":"İsim","de":"A large cup or goblet, typically used for drinking wine in a Christian Eucharist","dt":"Genellikle Hristiyan ayinlerinde kullanılan büyük kadeh","e1":"A golden chalice.","e1t":"Altın kadeh.","e2":"The holy chalice.","e2t":"Kutsal kadeh."},{"w":"chameleon","tr":"bukalemun / değişken kişi","te":"Noun","tt":"İsim","de":"A lizard that changes color; or a person who changes their behavior or opinions according to the situation","dt":"Renk değiştiren kertenkele; veya duruma göre fikir değiştiren kişi","e1":"A political chameleon.","e1t":"Siyasi bir bukalemun (nabza göre şerbet veren).","e2":"The chameleon blended with the leaves.","e2t":"Bukalemun yapraklarla uyum sağladı."},{"w":"charisma","tr":"karizma / büyüleyicilik","te":"Noun","tt":"İsim","de":"Compelling attractiveness or charm that can inspire devotion in others","dt":"Başkalarında hayranlık uyandıran çekicilik veya büyüleyicilik","e1":"He has a lot of personal charisma.","e1t":"Çok fazla kişisel karizması var.","e2":"Charismatic leader.","e2t":"Karizmatik lider."},{"w":"charlatan","tr":"şarlatan / sahte doktor / dolandırıcı","te":"Noun","tt":"İsim","de":"A person falsely claiming to have a special knowledge or skill","dt":"Özel bir bilgi veya yeteneği varmış gibi davranan (sahtekar) kişi","e1":"He was exposed as a charlatan.","e1t":"Şarlatan olduğu ortaya çıktı.","e2":"Medical charlatans.","e2t":"Sahte doktorlar."},{"w":"chary","tr":"ihtiyatlı / çekingen / sakınan","te":"Adjective","tt":"Sıfat","de":"Cautiously or suspiciously reluctant to do something","dt":"Bir şeyi yapma konusunda ihtiyatlı veya şüpheci (çekingen)","e1":"Chary of making compliments.","e1t":"İltifat etme konusunda çekingen.","e2":"To be chary of investing.","e2t":"Yatırım yapma konusunda ihtiyatlı davranmak."},{"w":"chassis","tr":"şasi / kasa","te":"Noun","tt":"İsim","de":"The base frame of a motor vehicle or other mobile object","dt":"Bir motorlu aracın veya nesnenin temel iskeleti/şasisi","e1":"The car's chassis was damaged.","e1t":"Arabanın şasisi hasar görmüştü.","e2":"Lightweight chassis.","e2t":"Hafif şasi."},{"w":"chaste","tr":"iffetli / temiz / sade (stil)","te":"Adjective","tt":"Sıfat","de":"Abstaining from extramarital, or from all, sexual intercourse; or simple in style","dt":"Cinsel ilişkiden kaçınan (iffetli); veya tarz olarak sade/saf","e1":"To lead a chaste life.","e1t":"İffetli bir hayat sürmek.","e2":"A chaste prose style.","e2t":"Sade (abartısız) bir nesir tarzı."},{"w":"chasten","tr":"terbiye etmek / (ceza ile) yola getirmek / yumuşatmak","te":"Verb","tt":"Fiil","de":"(Of a misfortune) have a restraining or moderating effect on","dt":"(Bir talihsizliğin) birini terbiye etmesi veya gururunu kırması","e1":"He was chastened by the experience.","e1t":"Bu deneyim onu terbiye etti (akıllandırdı).","e2":"A chastened mood.","e2t":"Yatışmış (uslanmış) bir ruh hali."},{"w":"chastise","tr":"cezalandırmak / şiddetle azarlamak","te":"Verb","tt":"Fiil","de":"Rebuke or reprimand severely","dt":"Şiddetle azarlamak veya cezalandırmak","e1":"To chastise a child for misbehaving.","e1t":"Bir çocuğu yaramazlık yaptığı için azarlamak.","e2":"He was chastised by the critics.","e2t":"Eleştirmenler tarafından yerden yere vuruldu."},{"w":"chauvinist","tr":"şovenist / aşırı milliyetçi / erkek üstünlükçü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person displaying aggressive or exaggerated patriotism; or showing excessive loyalty to a group","dt":"Saldırgan veya abartılı vatanseverlik gösteren kişi; veya kendi grubuna aşırı bağlı olan","e1":"A male chauvinist.","e1t":"Erkek üstünlükçü (kadınları aşağı gören).","e2":"Chauvinistic attitudes.","e2t":"Şovenist tavırlar."},{"w":"checkered / chequered","tr":"kareli / inişli çıkışlı / şüpheli (geçmiş)","te":"Adjective","tt":"Sıfat","de":"Marked by periods of varied fortune or discreditable incidents; or having a pattern of squares","dt":"Değişken şans dönemleri veya utanç verici olaylarla işaretlenmiş (inişli çıkışlı); veya kareli","e1":"A checkered career.","e1t":"İnişli çıkışlı (parlak ve karanlık dönemleri olan) bir kariyer.","e2":"A checkered flag.","e2t":"Damalı bayrak (yarışlarda)."},{"w":"cherubic","tr":"melek gibi / masum ve tombul","te":"Adjective","tt":"Sıfat","de":"Having the childlike innocence or plump prettiness of a cherub","dt":"Bir meleğin (kerubim) çocuksu masumiyetine veya tombul güzelliğine sahip olan","e1":"A cherubic face.","e1t":"Melek gibi (masum) bir yüz.","e2":"Cherub (noun: tombul melek figürü).","e2t":""},{"w":"chicanery","tr":"hile / kurnazlık / dolap çevirme","te":"Noun","tt":"İsim","de":"The use of trickery to achieve a political, financial, or legal purpose","dt":"Siyasi, mali veya hukuki bir amaç için yapılan hilekarlık","e1":"Legal chicanery.","e1t":"Hukuki oyunlar (hileler).","e2":"He was accused of chicanery.","e2t":"Dolap çevirmekle suçlandı."},{"w":"chimerical / chimeric","tr":"hayali / imkansız / kuruntu ürünü","te":"Adjective","tt":"Sıfat","de":"(Of a hope or grievance) hoped for but illusory or impossible to achieve","dt":"Umulan ancak hayali veya başarılması imkansız olan","e1":"Chimerical dreams.","e1t":"Gerçekleşmesi imkansız hayaller.","e2":"Chimerical projects.","e2t":"Hayal ürünü projeler."},{"w":"chisel","tr":"keski / iskarpela / dolandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long","dt":"bladed hand tool with a beveled cutting edge; or to cheat or swindle","e1":"Keski (alet); veya dolandırmak (argo)","e1t":"He used a chisel to shape the wood.","e2":"Ahşabı şekillendirmek için keski kullandı.","e2t":"Chiseled features (sharp and well"},{"w":"chivalrous","tr":"centilmen / şövalye ruhlu / nazik","te":"Adjective","tt":"Sıfat","de":"(Of a man or his behavior) courteous and gallant, especially towards women","dt":"(Erkek için) nazik ve yiğit (özellikle kadınlara karşı)","e1":"A chivalrous gesture.","e1t":"Centilmence bir jest.","e2":"Chivalry (noun).","e2t":"Centilmenlik / Şövalyelik."},{"w":"choleric","tr":"öfkeli / hırçın / çabuk kızan","te":"Adjective","tt":"Sıfat","de":"Bad","dt":"tempered or irritable","e1":"Kötü huylu veya sinirli","e1t":"A choleric disposition.","e2":"Hırçın bir mizaç.","e2t":"He was a choleric man, prone to outbursts."},{"w":"choreography","tr":"koreografi / dans düzenleme","te":"Noun","tt":"İsim","de":"The sequence of steps and movements in dance","dt":"Danstaki adım ve hareketlerin dizilimi","e1":"The choreography for the ballet.","e1t":"Bale için koreografi.","e2":"To choreograph a performance.","e2t":"Bir gösteriyi koreografize etmek (düzenlemek)."},{"w":"chortle","tr":"kıkırdamak / neşeyle gülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Laugh in a breathy, gleeful way; a chuckle","dt":"Neşeli ve boğuk bir şekilde gülmek/kıkırdamak","e1":"He chortled with delight.","e1t":"Büyük bir neşeyle kıkırdadı.","e2":"A deep chortle.","e2t":"Derinden bir kıkırdama."},{"w":"chronicle","tr":"vakaüname / kronik / kaydetmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A factual written account of important or historical events in the order of their occurrence; or to record","dt":"Tarihsel olayların oluş sırasına göre yazılı kaydı; veya kaydetmek","e1":"The Anglo","e1t":"Saxon Chronicle.","e2":"Anglo","e2t":"Sakson Vakaünamesi."},{"w":"churlish","tr":"kaba / aksi / görgüsüz","te":"Adjective","tt":"Sıfat","de":"Rude in a mean","dt":"spirited and surly way","e1":"Kaba, huysuz ve nezaketsiz","e1t":"It seems churlish to complain.","e2":"Şikayet etmek kaba bir davranış gibi görünüyor.","e2t":"A churlish remark."},{"w":"cipher","tr":"şifre / önemsiz kimse / sıfır","te":"Noun/Verb","tt":"İsim/Fiil","de":"A secret or disguised way of writing; a code; or a person of no importance","dt":"Gizli yazı (şifre); veya hiçbir önemi olmayan kişi","e1":"To write in cipher.","e1t":"Şifreli yazmak.","e2":"He was a mere cipher in the company.","e2t":"Şirkette hiçbir hükmü olmayan (önemsiz) biriydi."},{"w":"circlet","tr":"halka / taç (küçük)","te":"Noun","tt":"İsim","de":"A circular band, typically one made of precious metal, worn on the head as an ornament","dt":"Genellikle başa takılan değerli metalden halka/taç","e1":"A circlet of gold.","e1t":"Altından bir halka (taç).","e2":"A circlet of flowers.","e2t":"Çiçekten halka."},{"w":"circuitous","tr":"dolambaçlı / uzun yoldan","te":"Adjective","tt":"Sıfat","de":"(Of a route or journey) longer than the most direct way; indirect","dt":"(Rota için) doğrudan yoldan daha uzun; dolambaçlı","e1":"A circuitous route to the airport.","e1t":"Havaalanına giden dolambaçlı bir yol.","e2":"Circuitous reasoning.","e2t":"Dolambaçlı akıl yürütme."},{"w":"circumference","tr":"çevre (daire vb.)","te":"Noun","tt":"İsim","de":"The enclosing boundary of a curved geometric figure, especially a circle","dt":"Eğri bir geometrik şeklin, özellikle bir dairenin çevre uzunluğu","e1":"The circumference of the Earth.","e1t":"Dünya'nın çevresi.","e2":"To measure the circumference.","e2t":"Çevreyi ölçmek."},{"w":"circumlocution","tr":"dolambaçlı konuşma / kelime kalabalığı","te":"Noun","tt":"İsim","de":"The use of many words where fewer would do, especially in a deliberate attempt to be vague","dt":"Özellikle belirsiz olmak için az kelime yerine çok kelime kullanma","e1":"To avoid a direct answer with circumlocution.","e1t":"Dolambaçlı laflarla doğrudan cevaptan kaçınmak.","e2":"Legal circumlocutions.","e2t":"Hukuki kelime kalabalıkları."},{"w":"circumscribe","tr":"sınırlamak / kısıtlamak / çevresine çizgi çekmek","te":"Verb","tt":"Fiil","de":"Restrict (something) within limits; or to draw a figure round another","dt":"(Bir şeyi) sınırlar içinde tutmak (kısıtlamak); veya bir şeklin çevresine başka bir şekil çizmek","e1":"Their powers were circumscribed by the new law.","e1t":"Yetkileri yeni yasayla sınırlandırıldı.","e2":"A circumscribed area.","e2t":"Sınırlandırılmış bölge."},{"w":"circumspect","tr":"ihtiyatlı / tedbirli / ağzı sıkı","te":"Adjective","tt":"Sıfat","de":"Wary and unwilling to take risks","dt":"Dikkatli ve risk almaktan kaçınan","e1":"To be circumspect in your dealings.","e1t":"İlişkilerinde ihtiyatlı olmak.","e2":"A circumspect reply.","e2t":"Tedbirli (düşünülerek verilmiş) bir cevap."},{"w":"cistern","tr":"sarnıç / depo (su)","te":"Noun","tt":"İsim","de":"A tank for storing water, especially one supplying taps or as part of a flushing toilet","dt":"Su depolama tankı; sarnıç","e1":"To fill the cistern.","e1t":"Sarnıcı doldurmak.","e2":"Toilet cistern.","e2t":"Rezervuar (tuvalet deposu)."},{"w":"citadel","tr":"kale / hisar / sığınak","te":"Noun","tt":"İsim","de":"A fortress, typically on high ground, protecting or dominating a city","dt":"Şehri koruyan, genellikle yüksek yerdeki kale","e1":"The citadel overlooks the city.","e1t":"Kale şehre yukarıdan bakıyor.","e2":"A citadel of free speech.","e2t":"Özgür düşüncenin kalesi."},{"w":"clamber","tr":"tırmanmak (güçlükle)","te":"Verb/Noun","tt":"Fiil/İsim","de":"Climb or move in an awkward and laborious way, typically using both hands and feet","dt":"Genellikle el ve ayakları kullanarak güçlükle tırmanmak","e1":"To clamber up a steep hill.","e1t":"Dik bir tepeye güçlükle tırmanmak.","e2":"They clambered over the rocks.","e2t":"Kayaların üzerinden tırmanarak geçtiler."},{"w":"clamor / clamour","tr":"gürültü / feryat / ısrarla istemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A loud and confused noise, especially that of people shouting vehemently; or to make a protest","dt":"İnsanların bağırışından oluşan gürültü; veya ısrarla talep etmek","e1":"The clamor of the crowd.","e1t":"Kalabalığın gürültüsü.","e2":"To clamor for reform.","e2t":"Reform için bağırmak (ısrarla talep etmek)."},{"w":"clangor / clangour","tr":"çınlama / keskin metalik ses","te":"Noun","tt":"İsim","de":"A continuous loud banging or ringing sound","dt":"Sürekli, yüksek sesli çarpma veya çınlama sesi","e1":"The deafening clangor of the ironworks.","e1t":"Demirhanenin sağır edici metalik gürültüsü.","e2":"The clangor of church bells.","e2t":"Kilise çanlarının çınlaması."},{"w":"clapper","tr":"çan dili / şakşak","te":"Noun","tt":"İsim","de":"The device inside a bell that makes it ring; or a person who applauds","dt":"Çanın içinde ses çıkarmasını sağlayan metal parça; veya alkışlayan kişi","e1":"The clapper of the huge bronze bell was missing.","e1t":"Dev bronz çanın dili kayıptı.","e2":"Audience clappers.","e2t":"Alkışlayan izleyiciler."},{"w":"clasp","tr":"kenetlemek / tokalamak / sıkıca tutmak / toka","te":"Verb/Noun","tt":"Fiil/İsim","de":"Grasp something tightly with one's hand; or a device for fastening","dt":"Elle sıkıca tutmak/kavramak; veya bağlama aparatı (toka/klips)","e1":"He clasped her hand warmly.","e1t":"Elini sıcak bir şekilde kavradı.","e2":"The golden clasp of the necklace.","e2t":"Kolyenin altın tokası."},{"w":"claustrophobia","tr":"klostrofobi / kapalı alan korkusu","te":"Noun","tt":"İsim","de":"Extreme or irrational fear of confined places","dt":"Kapalı veya dar alanlara karşı aşırı korku","e1":"He suffers from claustrophobia.","e1t":"Klostrofobisi var.","e2":"The small elevator gave her a sense of claustrophobia.","e2t":"Küçük asansör onda kapalı alan korkusu yarattı."},{"w":"clavicle","tr":"köprücük kemiği","te":"Noun","tt":"İsim","de":"Either of the pair of bones joining the breastbone to the shoulder blades","dt":"Göğüs kemiğini omuz bıçaklarına bağlayan kemik çifti","e1":"He broke his left clavicle during the match.","e1t":"Maç sırasında sol köprücük kemiğini kırdı.","e2":"Fractured clavicle.","e2t":"Kırık köprücük kemiği."},{"w":"cleave","tr":"yarmak / bölmek / sadık kalmak","te":"Verb","tt":"Fiil","de":"Split or sever something; or stick fast to something","dt":"Bir şeyi yarmak veya ayırmak; veya bir şeye sıkıca bağlanmak/sadık kalmak","e1":"To cleave a block of wood.","e1t":"Bir odun bloğunu yarmak.","e2":"They cleave to their traditional beliefs.","e2t":"Geleneksel inançlarına sadık kalıyorlar."},{"w":"cleft","tr":"yarık / çatlak / yarılmış","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A fissure or split, especially one in rock or the ground","dt":"Özellikle kaya veya yerdeki yarık/çatlak","e1":"A cleft in the rocks.","e1t":"Kayalardaki bir yarık.","e2":"Cleft palate.","e2t":"Yarık damak (tıbbi durum)."},{"w":"clemency","tr":"merhamet / müsamaha / yumuşaklık (hava)","te":"Noun","tt":"İsim","de":"Mercy; lenience; or mildness of weather","dt":"Merhamet; hoşgörü; veya havanın yumuşaklığı","e1":"The prisoner pleaded for clemency.","e1t":"Mahkum merhamet (af) diledi.","e2":"To show clemency to the losers.","e2t":"Kaybedenlere merhamet göstermek."},{"w":"cliché / cliche","tr":"klişe / basmakalıp söz","te":"Noun","tt":"İsim","de":"A phrase or opinion that is overused and betrays a lack of original thought","dt":"Çok fazla kullanılmış ve özgünlükten uzak söz veya fikir","e1":"His speech was full of clichés.","e1t":"Konuşması klişelerle doluydu.","e2":"It has become a bit of a cliché.","e2t":"Bu biraz klişe haline geldi."},{"w":"climactic","tr":"doruk noktası ile ilgili / zirve teşkil eden","te":"Adjective","tt":"Sıfat","de":"(Of an action, event, or scene) forming an exciting climax","dt":"Heyecan verici bir doruk noktası oluşturan","e1":"The film's climactic battle scene.","e1t":"Filmin doruk noktası olan (final) savaş sahnesi.","e2":"A climactic moment in history.","e2t":"Tarihin dönüm noktası (zirve anı). (Not: 'Climatic'"},{"w":"clime","tr":"iklim / bölge / diyar","te":"Noun","tt":"İsim","de":"A region considered with particular reference to its climate","dt":"Özellikle iklimiyle anılan bölge veya diyar","e1":"In sunnier climes.","e1t":"Daha güneşli diyarlarda (iklimlerde).","e2":"To travel to distant climes.","e2t":"Uzak diyarlara seyahat etmek."},{"w":"clique","tr":"klik / zümre / dar grup","te":"Noun","tt":"İsim","de":"A small group of people, with shared interests, who spend time together and exclude others","dt":"Ortak çıkarları olan, birlikte vakit geçiren ve başkalarını dışlayan dar grup","e1":"The school was dominated by small cliques.","e1t":"Okula küçük klikler (gruplar) hakimdi.","e2":"Cliquery (noun).","e2t":"Klikleşme."},{"w":"cloister","tr":"revak / manastır / dünyadan elini çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A covered walk in a convent, monastery, or cathedral; or to seclude","dt":"Manastır veya katedraldeki kemerli yürüyüş yolu; veya (birini) dış dünyadan izole etmek","e1":"The quiet cloisters of the abbey.","e1t":"Manastırın sessiz revakları.","e2":"A cloistered life.","e2t":"Dış dünyadan soyutlanmış (manastır gibi) bir hayat."},{"w":"clout","tr":"nüfuz / güç / darbe / tokatlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Influence or power, especially in politics or business; or a heavy blow","dt":"Özellikle siyaset veya iş dünyasında nüfuz/etki; veya ağır darbe","e1":"Political clout.","e1t":"Siyasi nüfuz (güç).","e2":"He gave the boy a clout on the head.","e2t":"Çocuğun kafasına bir tane patlattı (vurdu)."},{"w":"cloying","tr":"baygın / fazla tatlı / usandırıcı","te":"Adjective","tt":"Sıfat","de":"Disgusting or distasteful by reason of excess; or sickly sweet","dt":"Aşırılığı nedeniyle tiksindirici; veya (ilgi/tat için) baygın/usandırıcı","e1":"The cloying smell of lilies.","e1t":"Zambakların baygın kokusu.","e2":"A cloying sentimentality.","e2t":"İnsanı bayacak kadar aşırı duygusallık."},{"w":"coagulate","tr":"pıhtılaşmak / katılaşmak","te":"Verb","tt":"Fiil","de":"(Of a fluid, especially blood) change to a solid or semi","dt":"solid state","e1":"(Sıvı, özellikle kan için) katı veya yarı katı hale geçmek","e1t":"Blood begins to coagulate in the air.","e2":"Kan havada pıhtılaşmaya başlar.","e2t":"Coagulation (noun)."},{"w":"coalesce","tr":"birleşmek / kaynaşmak / bütünleşmek","te":"Verb","tt":"Fiil","de":"Come together to form one mass or whole","dt":"Bir bütün oluşturmak için bir araya gelmek","e1":"The various factions coalesced into a single party.","e1t":"Çeşitli gruplar birleşerek tek bir parti oluşturdu.","e2":"Coalescence (noun).","e2t":"Birleşme."},{"w":"coddle","tr":"üstüne titremek / şımartmak / (yumurtayı) hafif haşlamak","te":"Verb","tt":"Fiil","de":"Treat in an indulgent or overprotective way; or to cook in water below boiling point","dt":"Birine aşırı ilgi gösterip şımartmak veya korumacı davranmak; veya hafifçe haşlamak","e1":"Don't coddle the child too much.","e1t":"Çocuğun üstüne çok fazla titreme (şımartma).","e2":"Coddled eggs.","e2t":"Hafif haşlanmış (rafadan) yumurta."},{"w":"codicil","tr":"vasiyetnameye ek","te":"Noun","tt":"İsim","de":"An addition or supplement that explains, modifies, or revokes a will","dt":"Bir vasiyeti açıklayan, değiştiren veya iptal eden ek belge","e1":"He added a codicil to his will.","e1t":"Vasiyetine bir ek (zeyilname) ekledi.","e2":"A secret codicil.","e2t":"Gizli vasiyet eki."},{"w":"codify","tr":"yasalaştırmak / düzenlemek / sistemleştirmek","te":"Verb","tt":"Fiil","de":"Arrange (laws or rules) into a systematic code","dt":"(Kanun veya kuralları) sistemli bir bütün (kod) haline getirmek","e1":"To codify the laws of the country.","e1t":"Ülke yasalarını sistemleştirmek (kodifiye etmek).","e2":"Codification (noun).","e2t":"Yasalaştırma / Düzenleme."},{"w":"coercion","tr":"zorlama / baskı / cebir","te":"Noun","tt":"İsim","de":"The practice of persuading someone to do something by using force or threats","dt":"Birini güç veya tehdit kullanarak bir şey yapmaya ikna etme pratiği","e1":"Confessions obtained under coercion.","e1t":"Baskı altında alınan itiraflar.","e2":"Economic coercion.","e2t":"Ekonomik zorlama."},{"w":"coeval","tr":"çağdaş / aynı yaştaki","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having the same age or date of origin; contemporary","dt":"Aynı yaşta olan veya aynı dönemde ortaya çıkan; çağdaş","e1":"These two buildings are coeval.","e1t":"Bu iki bina aynı döneme aittir (çağdaştır).","e2":"Coeval with the invention of the wheel.","e2t":"Tekerleğin icadıyla aynı döneme denk gelen."},{"w":"cogent","tr":"ikna edici / güçlü / mantıklı","te":"Adjective","tt":"Sıfat","de":"(Of an argument or case) clear, logical, and convincing","dt":"(İddia için) net, mantıklı ve ikna edici","e1":"A cogent argument for reform.","e1t":"Reform için ikna edici (güçlü) bir argüman.","e2":"She presented a cogent case.","e2t":"Mantıklı ve tutarlı bir savunma sundu."},{"w":"cogitate","tr":"derin düşünmek / tasarlamak","te":"Verb","tt":"Fiil","de":"Think deeply about something; meditate","dt":"Bir şey üzerinde derin derin düşünmek","e1":"He sat there, cogitating on his future.","e1t":"Geleceği üzerine derin düşüncelere dalarak orada oturdu.","e2":"Cogitation (noun).","e2t":"Derin düşünce."},{"w":"cognate","tr":"akraba / benzer / kökeni aynı olan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Related; connected; or having the same linguistic derivation","dt":"Akraba; bağlantılı; veya aynı dilsel kökene sahip olan","e1":"English \"father\" and German \"vater\" are cognate words.","e1t":"İngilizce \"father\" ve Almanca \"vater\" kökteş (benzer) kelimelerdir.","e2":"Cognate languages.","e2t":"Akraba diller."},{"w":"cognitive","tr":"bilişsel / zihinsel","te":"Adjective","tt":"Sıfat","de":"Relating to the mental action or process of acquiring knowledge and understanding","dt":"Bilgi edinme ve anlama gibi zihinsel süreçlerle ilgili","e1":"Cognitive development in children.","e1t":"Çocuklarda bilişsel gelişim.","e2":"Cognitive behavioral therapy (CBT).","e2t":"Bilişsel davranışçı terapi."},{"w":"cognizance / cognisance","tr":"farkındalık / bilgi / yargılama yetkisi","te":"Noun","tt":"İsim","de":"Knowledge, awareness, or notice; or judicial notice","dt":"Bilgi, farkındalık veya dikkat; veya hukuki yetki/bilgi","e1":"To have cognizance of the facts.","e1t":"Gerçeklerin farkında olmak (bilgisine sahip olmak).","e2":"To take cognizance of a situation (official).","e2t":"Bir durumu (resmen) dikkate almak."},{"w":"cohabit","tr":"birlikte yaşamak (nikahsız)","te":"Verb","tt":"Fiil","de":"Live together and have a sexual relationship without being married","dt":"Evli olmadan birlikte yaşamak ve ilişki sürdürmek","e1":"They have been cohabiting for ten years.","e1t":"On yıldır nikahsız beraber yaşıyorlar.","e2":"Cohabitation (noun).","e2t":"Birlikte yaşama."},{"w":"cohere","tr":"uyumlu olmak / birbirine bağlanmak / yapışmak","te":"Verb","tt":"Fiil","de":"Be united; form a whole; or to be logically consistent","dt":"Birleşmek; bir bütün oluşturmak; veya mantıksal olarak tutarlı olmak","e1":"The story doesn't cohere.","e1t":"Hikaye (mantıksal olarak) bütünlük arz etmiyor (tutarsız).","e2":"To cohere to a surface.","e2t":"Bir yüzeye yapışmak."},{"w":"cohesion","tr":"bağlılık / uyum / tutunma","te":"Noun","tt":"İsim","de":"The action or fact of forming a united whole","dt":"Birleşik bir bütün oluşturma eylemi veya gerçeği","e1":"Social cohesion.","e1t":"Sosyal bağlılık (uyum).","e2":"Molecular cohesion.","e2t":"Moleküler tutunma (kohezyon)."},{"w":"cohort","tr":"grup / kuşak / bölük","te":"Noun","tt":"İsim","de":"A group of people with a shared characteristic; or an ancient Roman military unit","dt":"Ortak özelliği olan insan grubu; veya eski Roma askeri birliği","e1":"A cohort of students.","e1t":"Bir grup (kuşak) öğrenci.","e2":"My cohorts (my colleagues/friends).","e2t":"Arkadaşlarım / Ortaklarım."},{"w":"coiffure","tr":"saç tuvaleti / saç modeli","te":"Noun","tt":"İsim","de":"A person's hairstyle, typically an elaborate one","dt":"Genellikle özenle yapılmış saç modeli","e1":"An elegant coiffure.","e1t":"Zarif bir saç tuvaleti.","e2":"To arrange one's coiffure.","e2t":"Saçını yaptırmak."},{"w":"coincidence","tr":"tesadüf / rastlantı / çakışma","te":"Noun","tt":"İsim","de":"A remarkable concurrence of events or circumstances without apparent causal connection","dt":"Belirgin bir neden","e1":"sonuç ilişkisi olmadan olayların dikkat çekici şekilde çakışması","e1t":"What a coincidence!","e2":"Ne tesadüf!","e2t":"By sheer coincidence."},{"w":"colander","tr":"süzgeç / kevgir","te":"Noun","tt":"İsim","de":"A perforated bowl used to strain off liquid from food","dt":"Yiyeceklerin suyunu süzmek için kullanılan delikli kap","e1":"Drain the pasta in a colander.","e1t":"Makarnayı süzgeçte süzün.","e2":"A plastic colander.","e2t":"Plastik süzgeç."},{"w":"collage","tr":"kolaj / yapıştırma resim","te":"Noun","tt":"İsim","de":"A piece of art made by sticking various different materials such as photographs and pieces of paper or fabric onto a backing","dt":"Fotoğraf, kağıt veya kumaş parçalarının yapıştırılmasıyla oluşturulan sanat eseri","e1":"To make a collage.","e1t":"Kolaj yapmak.","e2":"A collage of memories.","e2t":"Anılar bütünü (kolajı)."},{"w":"collate","tr":"karşılaştırmak / (sayfaları) sıraya dizmek","te":"Verb","tt":"Fiil","de":"Collect and combine (texts, information, or figures) in proper order; or to compare","dt":"(Metin veya bilgileri) uygun sırayla bir araya getirmek; veya karşılaştırmak","e1":"To collate the data from various sources.","e1t":"Çeşitli kaynaklardan gelen verileri bir araya getirip (karşılaştırıp) düzenlemek.","e2":"To collate the pages of a report.","e2t":"Raporun sayfalarını sıraya dizmek."},{"w":"colloquy","tr":"konuşma / müzakere / diyalog","te":"Noun","tt":"İsim","de":"A gathering for discussion of theological or public interest (formal)","dt":"Tartışma veya müzakere amaçlı toplantı (resmi)","e1":"An academic colloquy.","e1t":"Akademik bir görüşme (diyalog).","e2":"To hold a private colloquy.","e2t":"Özel bir müzakere yürütmek."},{"w":"collusion","tr":"gizli anlaşma / danışıklı dövüş / şike","te":"Noun","tt":"İsim","de":"Secret or illegal cooperation or conspiracy, especially in order to deceive others","dt":"Başkalarını aldatmak için yapılan gizli veya yasa dışı işbirliği","e1":"They were in collusion with the enemy.","e1t":"Düşmanla gizli anlaşma içindeydiler.","e2":"To act in collusion.","e2t":"Danışıklı dövüş içinde olmak."},{"w":"colossus","tr":"dev heykel / devasa şey veya kişi","te":"Noun","tt":"İsim","de":"A person or thing of enormous size, importance, or ability","dt":"Çok büyük boyutlu, önemli veya yetenekli kişi veya nesne","e1":"The Colossus of Rhodes.","e1t":"Rodos Heykeli (Dünyanın yedi harikasından biri).","e2":"An intellectual colossus.","e2t":"Entelektüel bir dev."},{"w":"comatose","tr":"komada / derin uykuda / bitkin","te":"Adjective","tt":"Sıfat","de":"Of or in a state of deep unconsciousness for a prolonged or indefinite period","dt":"Uzun süreli veya belirsiz derin bilinçsizlik durumunda; veya aşırı bitkin/uyuşuk","e1":"The patient remains comatose.","e1t":"Hasta komada kalmaya devam ediyor.","e2":"I was practically comatose after the long flight.","e2t":"Uzun uçuştan sonra resmen bitkin (yarı baygın) bir haldeydim."},{"w":"combustible","tr":"yanıcı / parlayıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to catch fire and burn easily","dt":"Kolayca alev alabilen ve yanabilen","e1":"Combustible materials.","e1t":"Yanıcı maddeler.","e2":"A highly combustible situation (explosive).","e2t":"Her an patlak verebilecek (tehlikeli) bir durum."},{"w":"comely","tr":"güzel / çekici / hoş (kadın)","te":"Adjective","tt":"Sıfat","de":"(Of a woman) pleasant to look at; attractive","dt":"(Kadın için) bakması hoş; çekici","e1":"A comely young lady.","e1t":"Hoş (güzel) bir genç hanım.","e2":"Comeliness (noun).","e2t":"Güzellik / Alımlılık."},{"w":"comestible","tr":"yiyecek / yenilebilir şey","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An item of food (formal)","dt":"Yiyecek maddesi (resmi)","e1":"Exotic comestibles.","e1t":"Egzotik yiyecekler.","e2":"Comestible oils.","e2t":"Yenilebilir yağlar."},{"w":"comeuppance","tr":"hak edilen ceza / payını alma","te":"Noun","tt":"İsim","de":"A punishment or fate that someone deserves","dt":"Birinin hak ettiği ceza veya akıbet","e1":"He finally got his comeuppance for his crimes.","e1t":"Sonunda işlediği suçlar için payını aldı (hak ettiği cezayı buldu).","e2":"To wait for someone's comeuppance.","e2t":"Birinin cezasını çekmesini beklemek."},{"w":"comity","tr":"nezaket / dostluk / devletler arası saygı","te":"Noun","tt":"İsim","de":"Courtesy and considerate behavior towards others; or mutual recognition of executive, legislative, and judicial acts by nations","dt":"Başkalarına karşı nazik davranış; veya uluslararası hukukta karşılıklı nezaket ve tanıma","e1":"The comity of nations.","e1t":"Milletler arası nezaket (dostluk).","e2":"To behave with comity.","e2t":"Nezaketle hareket etmek."},{"w":"commandeer","tr":"el koymak / (zorla) hizmete almak","te":"Verb","tt":"Fiil","de":"Officially take possession of something, especially for military purposes","dt":"Özellikle askeri amaçlarla bir şeye resmen el koymak","e1":"The army commandeered the local vehicles.","e1t":"Ordu yerel araçlara el koydu.","e2":"To commandeer a ship.","e2t":"Bir gemiye el koymak."},{"w":"commemorate","tr":"anmak / anısına tören yapmak","te":"Verb","tt":"Fiil","de":"Recall and show respect for (someone or something)","dt":"Birini veya bir şeyi saygıyla hatırlamak (anmak)","e1":"A statue to commemorate the fallen soldiers.","e1t":"Şehit askerlerin anısına dikilen bir heykel.","e2":"To commemorate an anniversary.","e2t":"Bir yıldönümünü kutlamak/anmak."},{"w":"commensurate","tr":"uygun / orantılı / eşit","te":"Adjective","tt":"Sıfat","de":"Corresponding in size or degree; in proportion","dt":"Boyut veya derece bakımından uygun; orantılı","e1":"A salary commensurate with your experience.","e1t":"Deneyiminizle orantılı bir maaş.","e2":"The punishment should be commensurate with the crime.","e2t":"Ceza suçla orantılı (uygun) olmalıdır."},{"w":"commodious","tr":"geniş / ferah / rahat","te":"Adjective","tt":"Sıfat","de":"(Of a building or room) roomy and comfortable","dt":"(Bina veya oda için) geniş ve konforlu","e1":"A commodious apartment.","e1t":"Ferah bir daire.","e2":"A commodious desk.","e2t":"Geniş (kullanışlı) çalışma masası."},{"w":"communal","tr":"ortak / toplumsal / paylaşılan","te":"Adjective","tt":"Sıfat","de":"Shared by all members of a community; for common use","dt":"Bir topluluğun tüm üyeleri tarafından paylaşılan; ortak kullanım için","e1":"A communal kitchen.","e1t":"Ortak mutfak.","e2":"Communal living.","e2t":"Toplu (ortak) yaşam."},{"w":"compatible","tr":"uyumlu / bağdaşan","te":"Adjective","tt":"Sıfat","de":"(Of two things) able to exist or occur together without conflict","dt":"Çatışma olmadan bir arada bulunabilen (uyumlu)","e1":"This software is compatible with Windows.","e1t":"Bu yazılım Windows ile uyumludur.","e2":"They are a very compatible couple.","e2t":"Onlar çok uyumlu bir çift."},{"w":"compendium","tr":"özet / antoloji / el kitabı","te":"Noun","tt":"İsim","de":"A collection of concise but detailed information about a particular subject","dt":"Belirli bir konu hakkında kısa ama detaylı bilgiler koleksiyonu","e1":"A compendium of English grammar rules.","e1t":"İngilizce dil bilgisi kuralları özeti (el kitabı).","e2":"To publish a compendium of poems.","e2t":"Şiir seçkisi (antoloji) yayınlamak."},{"w":"compensatory","tr":"telafi edici / tazminat niteliğinde","te":"Adjective","tt":"Sıfat","de":"(Of a payment) intended to recompense someone who has experienced loss, suffering, or injury","dt":"Zarar, acı veya yaralanma yaşayan birini tazmin etmeyi amaçlayan","e1":"Compensatory damages.","e1t":"Telafi edici tazminat.","e2":"Compensatory education.","e2t":"Destekleyici (telafi edici) eğitim."},{"w":"complacency","tr":"rehavet / kendinden memnun olma (tehlikeli şekilde)","te":"Noun","tt":"İsim","de":"A feeling of smug or uncritical satisfaction with oneself or one's achievements","dt":"Kendinden veya başarılarından duyulan (genellikle tehlikelere karşı kör eden) aşırı memnuniyet","e1":"There is no room for complacency.","e1t":"Rehavete yer yok.","e2":"Complacent (adjective).","e2t":"Kendinden memnun / Rehavete kapılmış."},{"w":"complaisant","tr":"nazik / itaatkar / başkalarını memnun etmeye çalışan","te":"Adjective","tt":"Sıfat","de":"Willing to please others; obliging; agreeable","dt":"Başkalarını memnun etmeye istekli; uysal","e1":"A complaisant husband.","e1t":"Karısının her dediğini yapan (uysal) koca.","e2":"To be too complaisant with subordinates.","e2t":"Astlarına karşı fazla müsamahakar olmak. (Not: 'Complacent' ile karıştırılmamalıdır)."},{"w":"complicity","tr":"suç ortaklığı / iştirak","te":"Noun","tt":"İsim","de":"The state of being involved with others in an illegal activity or wrongdoing","dt":"Başkalarıyla birlikte yasa dışı bir eyleme veya yanlışa karışma durumu","e1":"He was accused of complicity in the crime.","e1t":"Suça iştirak etmekle (suç ortaklığıyla) suçlandı.","e2":"To deny any complicity.","e2t":"Herhangi bir ortaklığı reddetmek."},{"w":"comport","tr":"davranmak / bağdaşmak / uyum sağlamak","te":"Verb","tt":"Fiil","de":"To conduct oneself; behave; or to be in agreement with","dt":"Davranmak (kendini taşımak); veya ...ile bağdaşmak/uyumlu olmak","e1":"To comport oneself with dignity.","e1t":"Vakur (onurlu) davranmak.","e2":"Her actions do not comport with her words.","e2t":"Davranışları sözleriyle bağdaşmıyor."},{"w":"composure","tr":"soğukkanlılık / huzur / itidal","te":"Noun","tt":"İsim","de":"The state or feeling of being calm and in control of oneself","dt":"Sakin olma ve kendini kontrol etme durumu","e1":"To keep one's composure.","e1t":"Soğukkanlılığını korumak.","e2":"He regained his composure.","e2t":"İtinalini (sakinliğini) yeniden kazandı."},{"w":"compound","tr":"birleşik / bileşik / şiddetlendirmek / site (yerleşim)","te":"Noun/Verb/Adj","tt":"A thing that is composed of two or more separate elements; or to make a bad situation worse","de":"İki veya daha fazla öğeden oluşan şey; veya (kötü bir durumu) daha da kötüleştirmek","dt":"A chemical compound.","e1":"Kimyasal bileşik.","e1t":"His insults only compounded the problem.","e2":"Hakaretleri sorunu sadece şiddetlendirdi (katmerledi).","e2t":""},{"w":"compress","tr":"sıkıştırmak / özetlemek / kompres","te":"Verb/Noun","tt":"Fiil/İsim","de":"Flatten by pressure; or alter the form of data to reduce size; or a pad of absorbent material","dt":"Basınçla yassılaştırmak; veya veri boyutunu küçültmek; veya tıbbi pansuman (kompres)","e1":"To compress a file.","e1t":"Dosyayı sıkıştırmak.","e2":"To compress the air.","e2t":"Havayı sıkıştırmak."},{"w":"compunction","tr":"vicdan azabı / pişmanlık / tereddüt","te":"Noun","tt":"İsim","de":"A feeling of guilt or moral scruple that prevents or follows the doing of something bad","dt":"Kötü bir şey yapmayı engelleyen veya ardından gelen suçluluk duygusu","e1":"He had no compunction about lying.","e1t":"Yalan söyleme konusunda hiçbir vicdan azabı (tereddüdü) yoktu.","e2":"To feel a touch of compunction.","e2t":"Hafif bir pişmanlık hissetmek."},{"w":"concatenate","tr":"birbirine bağlamak / zincirleme","te":"Verb","tt":"Fiil","de":"Link (things) together in a chain or series (especially in computing)","dt":"(Özellikle bilgisayar biliminde) nesneleri bir zincir veya dizi halinde birbirine bağlamak","e1":"To concatenate strings of text.","e1t":"Metin dizilerini birbirine bağlamak.","e2":"Concatenation (noun).","e2t":"Zincirleme / Bağlama."},{"w":"concave","tr":"içbükey / obruk","te":"Adjective","tt":"Sıfat","de":"Having an outline or surface that curves inward like the interior of a circle or sphere","dt":"Bir dairenin veya kürenin içi gibi içe doğru kavisli yüzeyi olan","e1":"A concave lens.","e1t":"İçbükey mercek.","e2":"Concave mirror.","e2t":"Çukur ayna. (Not: 'Convex'"},{"w":"conceit","tr":"kibir / abartılı benzetme (edebiyat)","te":"Noun","tt":"İsim","de":"Excessive pride in oneself; or a fanciful expression in writing","dt":"Aşırı kibir (kendini beğenmişlik); veya yazıda hayal ürünü, abartılı benzetme","e1":"He's full of conceit.","e1t":"Çok kibirli (kendini beğenmiş).","e2":"A poetic conceit.","e2t":"Şiirsel bir teşbih (benzetme)."},{"w":"concentric","tr":"eş merkezli","te":"Adjective","tt":"Sıfat","de":"Of or denoting circles, arcs, or other shapes which share the same center","dt":"Aynı merkezi paylaşan daireler veya şekiller","e1":"Concentric circles.","e1t":"Eş merkezli daireler.","e2":"Concentric layers.","e2t":"Eş merkezli katmanlar."},{"w":"conception","tr":"kavram / anlayış / döllenme","te":"Noun","tt":"İsim","de":"The action of conceiving a child or of a child being conceived; or the forming of a plan or idea","dt":"Bir çocuğun döllenmesi; veya bir plan/fikrin oluşumu (kavram)","e1":"The conception of a new project.","e1t":"Yeni bir projenin tasarlanması (doğuşu).","e2":"Beyond my conception.","e2t":"Benim anlayışımın ötesinde."},{"w":"concerted","tr":"kararlaştırılmış / ortaklaşa / yoğun","te":"Adjective","tt":"Sıfat","de":"Jointly arranged, planned, or carried out; coordinated","dt":"Ortaklaşa planlanmış veya yürütülmüş; koordineli","e1":"A concerted effort.","e1t":"Ortak (yoğun) çaba.","e2":"A concerted attack.","e2t":"Kararlaştırılmış (planlı) saldırı."},{"w":"conciliatory","tr":"yatıştırıcı / uzlaşmacı / gönül alıcı","te":"Adjective","tt":"Sıfat","de":"Intended or likely to placate or pacify","dt":"Yatıştırmayı veya barıştırmayı amaçlayan","e1":"A conciliatory gesture.","e1t":"Uzlaşmacı bir jest.","e2":"To speak in a conciliatory tone.","e2t":"Yatıştırıcı bir tonla konuşmak."},{"w":"conclave","tr":"kapalı toplantı / gizli meclis","te":"Noun","tt":"İsim","de":"A private meeting, especially one held in secret","dt":"Özellikle gizli tutulan özel toplantı","e1":"The cardinals met in conclave to elect a new Pope.","e1t":"Kardinaller yeni Papa'yı seçmek için kapalı mecliste toplandılar.","e2":"A secret conclave of leaders.","e2t":"Liderlerin gizli toplantısı."},{"w":"conclusive","tr":"kesin / tartışmasız / nihai","te":"Adjective","tt":"Sıfat","de":"(Of evidence or an argument) serving to settle an issue; convincing","dt":"(Kanıt için) bir meseleyi çözen; tartışmasız ve ikna edici","e1":"Conclusive evidence.","e1t":"Kesin (nihai) kanıt.","e2":"A conclusive victory.","e2t":"Ezici (kesin) bir zafer."},{"w":"concomitant","tr":"beraberinde gelen / eşlik eden","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Naturally accompanying or associated","dt":"Doğal olarak eşlik eden veya ilişkili olan","e1":"Concomitant risks.","e1t":"Beraberinde gelen (eşlik eden) riskler.","e2":"A concomitant of old age.","e2t":"Yaşlılığın bir getirisi (parçası)."},{"w":"concord","tr":"uyum / anlaşma / dirlik","te":"Noun","tt":"İsim","de":"Agreement or harmony between people or groups","dt":"İnsanlar veya gruplar arasındaki uyum veya anlaşma","e1":"To live in concord with one's neighbors.","e1t":"Komşularıyla dirlik (uyum) içinde yaşamak.","e2":"A treaty of concord.","e2t":"Dostluk (barış) antlaşması."},{"w":"concur","tr":"hemfikir olmak / aynı anda olmak","te":"Verb","tt":"Fiil","de":"Be of the same opinion; agree; or happen at the same time","dt":"Aynı görüşte olmak (katılmak); veya aynı anda gerçekleşmek","e1":"I concur with your decision.","e1t":"Kararınıza katılıyorum.","e2":"Everything concurred to produce the result.","e2t":"Her şey sonucu doğurmak için aynı anda gerçekleşti (birleşti)."},{"w":"concurrent","tr":"eşzamanlı / çakışan / aynı anda olan","te":"Adjective","tt":"Sıfat","de":"Existing, happening, or done at the same time","dt":"Aynı anda mevcut olan veya yapılan","e1":"Concurrent events.","e1t":"Eşzamanlı olaylar.","e2":"Serving three concurrent sentences.","e2t":"Aynı anda çekilen üç ceza."},{"w":"condescend","tr":"tenezzül etmek / küçümsemek / tepeden bakmak","te":"Verb","tt":"Fiil","de":"Show feelings of superiority; patronize; or to do something that one considers to be below one's dignity","dt":"Üstünlük taslamak; veya (normalde yapmayacağı) bir şeyi lütfedip yapmak","e1":"Don't condescend to me!","e1t":"Bana tepeden bakma!","e2":"He finally condescended to help us.","e2t":"Sonunda bize yardım etmeye tenezzül etti (lütfetti)."},{"w":"condign","tr":"hak edilmiş / layık (ceza vb.)","te":"Adjective","tt":"Sıfat","de":"(Of punishment) appropriate to the crime or offense; deserved","dt":"(Ceza için) suça uygun; hak edilmiş (resmi)","e1":"Condign punishment.","e1t":"Hak edilmiş (layık görülen) ceza.","e2":"","e2t":""},{"w":"condiment","tr":"çeşni / sos / baharat","te":"Noun","tt":"İsim","de":"A substance such as salt or mustard that is used to add flavor to food","dt":"Yiyeceklere lezzet katmak için kullanılan tuz veya hardal gibi maddeler","e1":"Ketchup and mustard are common condiments.","e1t":"Ketçap ve hardal yaygın çeşnilerdir.","e2":"To season with various condiments.","e2t":"Çeşitli baharatlarla (çeşnilerle) tatlandırmak."},{"w":"condole","tr":"taziyede bulunmak / başsağlığı dilemek","te":"Verb","tt":"Fiil","de":"Express sympathy for someone; grieve with","dt":"Birine sempati (başsağlığı) ifade etmek; acısını paylaşmak","e1":"We condoled with him on the death of his father.","e1t":"Babasının ölümü üzerine ona taziyede bulunduk.","e2":"Condolence (noun).","e2t":"Taziye / Başsağlığı."},{"w":"conduit","tr":"kanal / boru / mecra","te":"Noun","tt":"İsim","de":"A channel for conveying water or other fluid; or a means by which something is transmitted","dt":"Su veya diğer sıvıları taşıyan kanal; veya bir şeyin iletildiği yol/vasıta","e1":"A conduit for electrical wires.","e1t":"Elektrik kabloları için koruyucu boru (kanal).","e2":"The organization served as a conduit for illegal funds.","e2t":"Kuruluş, yasa dışı fonlar için bir mecra (aracı) görevi gördü."},{"w":"conflagration","tr":"büyük yangın / afet","te":"Noun","tt":"İsim","de":"An extensive fire which destroys a great deal of land or property","dt":"Çok miktarda araziyi veya mülkü yok eden büyük yangın","e1":"The conflagration destroyed the entire village.","e1t":"Büyük yangın tüm köyü yok etti.","e2":"A nuclear conflagration (global conflict).","e2t":"Nükleer bir felaket (çatışma)."},{"w":"congeal","tr":"pıhtılaşmak / katılaşmak / donmak","te":"Verb","tt":"Fiil","de":"Solidify or coagulate, especially by cooling","dt":"Özellikle soğuyarak katılaşmak veya pıhtılaşmak","e1":"The blood had congealed on the wound.","e1t":"Yaradaki kan pıhtılaşmıştı.","e2":"The soup congealed in the fridge.","e2t":"Çorba buzdolabında katılaştı (dondu)."},{"w":"congenital","tr":"doğuştan gelen","te":"Adjective","tt":"Sıfat","de":"(Of a disease or physical abnormality) present from birth","dt":"(Hastalık veya anormallik için) doğumdan itibaren mevcut olan","e1":"A congenital heart defect.","e1t":"Doğuştan gelen kalp kusuru.","e2":"A congenital liar (habitual).","e2t":"Doğuştan (iflah olmaz) yalancı."},{"w":"congruent","tr":"uyumlu / eş (geometri)","te":"Adjective","tt":"Sıfat","de":"In agreement or harmony; or (geometry) identical in form","dt":"Uyum veya ahenk içinde; veya (geometri) biçim olarak özdeş/eş","e1":"Their goals are congruent with ours.","e1t":"Onların hedefleri bizimkilerle uyumludur.","e2":"Congruent triangles.","e2t":"Eş üçgenler."},{"w":"conifer","tr":"kozalaklı ağaç / iğne yapraklı","te":"Noun","tt":"İsim","de":"A tree that bears cones and needle","dt":"like or scale","e1":"like leaves that are typically evergreen","e1t":"Kozalak veren ve genellikle her mevsim yeşil kalan iğne yapraklı ağaç","e2":"Pine and fir are common conifers.","e2t":"Çam ve göknar yaygın kozalaklı ağaçlardır."},{"w":"conjugal","tr":"evlilikle ilgili / karı","te":"koca arası","tt":"Adjective","de":"Sıfat","dt":"Relating to marriage or the relationship of a married couple","e1":"Evlilikle veya evli çiftin ilişkisiyle ilgili","e1t":"Conjugal rights.","e2":"Evlilik hakları.","e2t":"Conjugal visit."},{"w":"connivance","tr":"göz yumma / suç ortaklığı","te":"Noun","tt":"İsim","de":"Willingness to allow or be secretly involved in an immoral or illegal act","dt":"Ahlaksız veya yasa dışı bir eyleme gizlice dahil olma veya göz yumma","e1":"This happened with the connivance of the officials.","e1t":"Bu durum yetkililerin göz yummasıyla (onayıyla) gerçekleşti.","e2":"Connive (verb).","e2t":"Göz yummak / Gizlice anlaşmak."},{"w":"connoisseur","tr":"eksper / uzman / zevk sahibi (sanat/yemek)","te":"Noun","tt":"İsim","de":"An expert judge in matters of taste","dt":"Tadım ve sanat gibi zevk meselelerinde uzman yargıç","e1":"A connoisseur of fine wines.","e1t":"Kaliteli şarapların uzmanı.","e2":"An art connoisseur.","e2t":"Sanat eksperi."},{"w":"connotation","tr":"yan anlam / çağrışım","te":"Noun","tt":"İsim","de":"An idea or feeling that a word invokes in addition to its literal or primary meaning","dt":"Bir kelimenin sözlük anlamının yanı sıra uyandırdığı fikir veya duygu","e1":"The word has negative connotations.","e1t":"Kelimenin olumsuz çağrışımları (yan anlamları) var.","e2":"Denotation and connotation.","e2t":"Düz anlam ve yan anlam."},{"w":"connubial","tr":"evlilikle ilgili / karı","te":"kocaya ait","tt":"Adjective","de":"Sıfat","dt":"Relating to marriage or the relationship of a married couple (formal)","e1":"Evlilikle ilgili (resmi/edebi)","e1t":"Connubial bliss.","e2":"Evlilik saadeti.","e2t":"(Conjugal ile eş anlamlıdır)."},{"w":"consanguinity","tr":"kan bağı / akrabalık","te":"Noun","tt":"İsim","de":"The property of being from the same kinship as another person","dt":"Başka bir kişiyle aynı soydan gelme özelliği (kan bağı)","e1":"The ties of consanguinity.","e1t":"Kan bağı bağları.","e2":"Consanguineous marriage.","e2t":"Akraba evliliği."},{"w":"conscript","tr":"askere çağırmak / zorunlu asker / askere alınmış","te":"Verb/Noun","tt":"Fiil/İsim","de":"Enlist (someone) compulsorily, typically into the armed services","dt":"Birini zorunlu olarak (genellikle orduya) kaydetmek","e1":"He was conscripted into the army.","e1t":"Askere alındı.","e2":"An army of conscripts.","e2t":"Zorunlu askerlerden oluşan ordu."},{"w":"consistency","tr":"tutarlılık / istikrar / yoğunluk (kıvam)","te":"Noun","tt":"İsim","de":"Conformity in the application of something, typically that which is necessary for the sake of logic, accuracy, or fairness; or thickness","dt":"Uygulamada tutarlılık; veya (sıvı için) koyuluk/kıvam","e1":"Consistency in his policy.","e1t":"Politikasındaki istikrar (tutarlılık).","e2":"The consistency of the sauce.","e2t":"Sosun kıvamı (yoğunluğu)."},{"w":"consonance","tr":"uyum / ahenk / ünsüz benzeşmesi","te":"Noun","tt":"İsim","de":"Agreement or compatibility between opinions or actions; or (music) combination of notes in harmony","dt":"Görüş veya eylemler arasındaki uyum; veya (müzik/edebiyat) ahenk/ses benzeşmesi","e1":"In consonance with our values.","e1t":"Değerlerimizle uyum içinde.","e2":"Consonance and dissonance (music).","e2t":"Uyum ve uyumsuzluk."},{"w":"consort","tr":"eş (hükümdarın) / arkadaşlık etmek / uyuşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A wife, husband, or companion, in particular the spouse of a reigning monarch; or to habitually associate with","dt":"Hükümdarın eşi; veya (kötü kişilerle) arkadaşlık etmek","e1":"The Prince Consort.","e1t":"Kraliçe'nin eşi olan prens.","e2":"To consort with criminals.","e2t":"Suçlularla düşüp kalkmak (arkadaşlık etmek)."},{"w":"contiguous","tr":"bitişik / komşu / yan yana","te":"Adjective","tt":"Sıfat","de":"Sharing a common border; touching","dt":"Ortak bir sınırı paylaşan; temas eden","e1":"The 48 contiguous states of the US.","e1t":"ABD'nin birbirine bitişik (anakara) 48 eyaleti.","e2":"The garden is contiguous to the fields.","e2t":"Bahçe tarlalarla bitişiktir."},{"w":"continence","tr":"özdenetim / (ihtiyaçlarını) tutabilme / nefsine hakim olma","te":"Noun","tt":"İsim","de":"Self","dt":"restraint, especially with regard to sexual impulses; or the ability to control bladder or bowel movements","e1":"Özellikle cinsel dürtüler üzerinde özdenetim; veya boşaltım sistemini kontrol edebilme yeteneği","e1t":"To practice emotional continence.","e2":"Duygusal özdenetim uygulamak.","e2t":"Urinary continence."},{"w":"contingent","tr":"bağlı / olasılı / grup (askeri/temsilci)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Subject to chance; or occurring only if certain circumstances are the first; or a group representing a larger organization","dt":"Şansa bağlı; veya ancak belirli koşullar gerçekleşirse olan; veya temsilci grubu","e1":"Our success is contingent on your support.","e1t":"Başarımız sizin desteğinize bağlıdır.","e2":"A large contingent of police.","e2t":"Büyük bir polis birliği (grubu)."},{"w":"contort","tr":"bükmek / biçimini bozmak / yamultmak","te":"Verb","tt":"Fiil","de":"Twist or bend out of its normal shape","dt":"Normal şeklinin dışına bükmek veya kıvırmak","e1":"His face was contorted with pain.","e1t":"Yüzü acıyla çarpılmıştı (bükülmüştü).","e2":"To contort your body.","e2t":"Vücudunu eğip bükmek."},{"w":"contrived","tr":"yapmacık / zorlama / uydurma","te":"Adjective","tt":"Sıfat","de":"Deliberately created rather than arising naturally or spontaneously; artificial","dt":"Doğal olarak ortaya çıkmaktan ziyade kasten oluşturulmuş; yapay","e1":"A highly contrived plot.","e1t":"Çok zorlama (uydurma) bir olay örgüsü.","e2":"Her smile seemed contrived.","e2t":"Gülümsemesi yapmacık görünüyordu."},{"w":"contumacious","tr":"inatçı / dikbaşlı / (mahkemeye) itaatsiz","te":"Adjective","tt":"Sıfat","de":"Stubbornly or willfully disobedient to authority","dt":"Otoriteye karşı inatla veya kasten itaatsiz olan","e1":"A contumacious witness.","e1t":"Mahkemeye itaatsizlik eden (direnen) tanık.","e2":"His contumacious behavior.","e2t":"Onun dikbaşlı (asi) davranışı."},{"w":"contusion","tr":"ezik / morluk / bere","te":"Noun","tt":"İsim","de":"A region of injured tissue or skin in which blood capillaries have been ruptured; a bruise","dt":"Kan kılcallarının patladığı yaralı doku veya deri bölgesi; morluk","e1":"He suffered severe cerebral contusions.","e1t":"Şiddetli beyin ezilmeleri (kontüzyon) yaşadı.","e2":"Multiple contusions on the body.","e2t":"Vücutta çok sayıda ezilme/morluk."},{"w":"conundrum","tr":"bilmece / muamma / içinden çıkılmaz sorun","te":"Noun","tt":"İsim","de":"A confusing and difficult problem or question","dt":"Kafa karıştırıcı ve zor problem veya soru","e1":"A difficult ethical conundrum.","e1t":"Zor bir etik muamma (bilmece).","e2":"To solve a conundrum.","e2t":"Bir bilmeceyi çözmek."},{"w":"conversant","tr":"aşina / bilgi sahibi /","te":"den anlayan","tt":"Adjective","de":"Sıfat","dt":"Familiar with or knowledgeable about something","e1":"Bir şeye aşina olan veya bir konuda bilgi sahibi olan","e1t":"To be conversant with the latest technology.","e2":"En son teknolojiye aşina olmak.","e2t":"I am not fully conversant with the facts."},{"w":"converse","tr":"karşıt / zıt / konuşmak","te":"Adjective/Noun/Verb","tt":"Opposite or contrary in direction, action, or meaning; or to talk","de":"Yön, eylem veya anlam bakımından karşıt (zıt); veya konuşmak","dt":"The converse is also true.","e1":"Bunun tersi de doğrudur.","e1t":"To converse with a friend.","e2":"Bir arkadaşla sohbet etmek.","e2t":""},{"w":"convex","tr":"dışbükey / tümsek","te":"Adjective","tt":"Sıfat","de":"Having an outline or surface curved like the exterior of a circle or sphere","dt":"Bir dairenin veya kürenin dışı gibi dışa doğru kavisli yüzeyi olan","e1":"A convex lens.","e1t":"Dışbükey mercek.","e2":"Convex mirror.","e2t":"Tümsek ayna. (Not: 'Concave'"},{"w":"conveyance","tr":"taşıma / vasıta / devir (tapu/mülk)","te":"Noun","tt":"İsim","de":"The action or process of transporting or carrying someone or something; or a vehicle; or the legal process of transferring property","dt":"Taşıma işlemi; veya vasıta; veya mülkiyetin yasal devri","e1":"Public conveyance (transport).","e1t":"Toplu taşıma.","e2":"The conveyance of information.","e2t":"Bilginin iletilmesi."},{"w":"convoke","tr":"toplantıya çağırmak / toplamak (resmi)","te":"Verb","tt":"Fiil","de":"Call together or summon (an assembly or meeting)","dt":"(Meclis veya toplantıyı) resmen çağırmak","e1":"To convoke a parliament.","e1t":"Parlamentoyu toplantıya çağırmak.","e2":"The king convoked his advisors.","e2t":"Kral danışmanlarını topladı."},{"w":"convoluted","tr":"karmaşık / dolambaçlı / girift","te":"Adjective","tt":"Sıfat","de":"(Of an argument, story, or sentence) extremely complex and difficult to follow","dt":"(İddia veya hikaye için) son derece karmaşık ve takibi zor","e1":"A convoluted explanation.","e1t":"Dolambaçlı (anlaşılmaz) bir açıklama.","e2":"Convoluted brain tissues.","e2t":"Kıvrımlı beyin dokuları."},{"w":"coquette","tr":"koket / cilveli kadın / şuh","te":"Noun","tt":"İsim","de":"A woman who flirts","dt":"Flörtöz (cilveli) kadın","e1":"She was a bit of a coquette.","e1t":"Biraz cilveli biriydi.","e2":"Coquettish (adjective).","e2t":"Cilveli."},{"w":"cordon","tr":"kordon / güvenlik şeridi / kuşatmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A line of police, soldiers, or guards preventing access to an area","dt":"Erişimi engellemek için kurulan polis veya asker hattı","e1":"A police cordon.","e1t":"Polis kordonu.","e2":"To cordon off an area.","e2t":"Bir bölgeyi kordon altına almak (giriş çıkışı kapatmak)."},{"w":"cornice","tr":"korniş / saçak / taç (mimari)","te":"Noun","tt":"İsim","de":"An ornamental molding round the wall of a room just below the ceiling; or a horizontal projection","dt":"Tavanın hemen altındaki duvar süslemesi (kartonpiyer); veya mimari saçak","e1":"Decorative plaster cornices.","e1t":"Dekoratif alçı kornişler.","e2":"A snow cornice (overhang).","e2t":"Kar saçağı (çıkıntısı)."},{"w":"cornucopia","tr":"bolluk / bereket boynuzu","te":"Noun","tt":"İsim","de":"A symbol of plenty consisting of a goat's horn overflowing with flowers, fruit, and corn","dt":"Çiçek ve meyvelerle dolu keçi boynuzu sembolü (bolluk simgesi)","e1":"The book is a cornucopia of information.","e1t":"Kitap bir bilgi hazinesidir (bolluğudur).","e2":"A cornucopia of fruits.","e2t":"Meyve bolluğu."},{"w":"corollary","tr":"doğal sonuç / ek öneri (matematik)","te":"Noun","tt":"İsim","de":"A proposition that follows from one already proved; or a direct or natural consequence","dt":"Zaten kanıtlanmış bir şeyden çıkan sonuç; veya doğrudan/doğal sonuç","e1":"A corollary to this theory.","e1t":"Bu teorinin bir sonucu.","e2":"Destruction is the natural corollary of war.","e2t":"Yıkım, savaşın doğal bir sonucudur."},{"w":"corporeal","tr":"bedensel / maddesel / somut","te":"Adjective","tt":"Sıfat","de":"Relating to a person's body, especially as opposed to their spirit; tangible","dt":"Ruhun aksine vücutla ilgili; maddesel veya somut","e1":"Corporeal needs.","e1t":"Bedensel ihtiyaçlar.","e2":"Corporeal world.","e2t":"Maddi dünya. (Not: 'Incorporeal'"},{"w":"corpulent","tr":"şişman / iri yarı / göbekli","te":"Adjective","tt":"Sıfat","de":"(Of a person) fat (formal)","dt":"(Kişi için) şişman (resmi/nazikçe)","e1":"A corpulent gentleman.","e1t":"İri yarı (şişman) bir beyefendi.","e2":"Corpulence (noun).","e2t":"Şişmanlık / Obezite."},{"w":"corrosive","tr":"aşındırıcı / yakıcı / yıkıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Tending to cause corrosion; or harmful and destructive","dt":"Aşınmaya neden olan; veya zararlı ve yıkıcı","e1":"Corrosive liquids.","e1t":"Aşındırıcı (yakıcı) sıvılar.","e2":"The corrosive effects of jealousy.","e2t":"Kıskançlığın kemirici (yıkıcı) etkileri."},{"w":"corrugated","tr":"oluklu / kıvrımlı / dalgalı","te":"Adjective","tt":"Sıfat","de":"(Of a material, surface, or structure) shaped into alternate ridges and grooves","dt":"(Malzeme için) oluk ve çıkıntılar halinde şekillendirilmiş","e1":"Corrugated iron.","e1t":"Oluklu sac.","e2":"Corrugated cardboard.","e2t":"Oluklu mukavva."},{"w":"cosmology","tr":"kozmoloji / evrenbilim","te":"Noun","tt":"İsim","de":"The science of the origin and development of the universe","dt":"Evrenin kökeni ve gelişimini inceleyen bilim","e1":"Modern cosmology.","e1t":"Modern evrenbilim.","e2":"Cosmological theories.","e2t":"Kozmolojik teoriler."},{"w":"coterie","tr":"klik / zümre / dar arkadaş çevresi","te":"Noun","tt":"İsim","de":"A small group of people with shared interests or tastes, especially one that is exclusive","dt":"Ortak ilgi alanları olan ve genellikle dışarıya kapalı küçük grup","e1":"A coterie of writers and artists.","e1t":"Yazarlar ve sanatçılardan oluşan bir zümre.","e2":"His private coterie.","e2t":"Onun özel arkadaş çevresi."},{"w":"countenance","tr":"yüz ifadesi / çehre / onaylamak / desteklemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person's face or facial expression; or to admit as acceptable or possible","dt":"Kişinin yüzü veya yüz ifadesi; veya kabul edilebilir bulmak (onaylamak)","e1":"Her calm countenance.","e1t":"Onun sakin yüz ifadesi.","e2":"The government would not countenance such a move.","e2t":"Hükümet böyle bir hamleyi onaylamaz (izin vermez)."},{"w":"countermand","tr":"iptal etmek / geri almak (emri)","te":"Verb/Noun","tt":"Fiil/İsim","de":"Revoke (an order)","dt":"(Verilmiş bir emri) iptal etmek","e1":"To countermand an order.","e1t":"Bir emri geri çekmek.","e2":"The general countermanded the attack.","e2t":"General saldırıyı iptal etti."},{"w":"coup","tr":"darbe / başarı / ani hamle","te":"Noun","tt":"İsim","de":"A sudden, violent, and illegal seizure of power from a government; or a notable or successful stroke or move","dt":"Hükümete yönelik ani ve yasa dışı güç kullanımı (darbe); veya dikkat çekici başarı/hamle","e1":"A military coup.","e1t":"Askeri darbe.","e2":"It was a major diplomatic coup for the president.","e2t":"Başkan için büyük bir diplomatik başarıydı."},{"w":"cozen","tr":"aldatmak / dolandırmak / kandırmak","te":"Verb","tt":"Fiil","de":"Trick or deceive; or obtain by deception","dt":"Kandırmak veya aldatmak; veya aldatma yoluyla elde etmek","e1":"He cozened the old lady out of her inheritance.","e1t":"Yaşlı kadını kandırarak mirasını elinden aldı.","e2":"To be cozened into a bad deal.","e2t":"Kötü bir anlaşmaya kandırılarak çekilmek."},{"w":"crabbed","tr":"okunması güç (yazı) / huysuz / aksi","te":"Adjective","tt":"Sıfat","de":"(Of handwriting) ill","dt":"formed and hard to decipher; or bad","e1":"tempered","e1t":"(El yazısı için) bozuk ve okunması zor; veya huysuz","e2":"Crabbed handwriting.","e2t":"Okunması çok zor (karman çorman) el yazısı."},{"w":"craftiness","tr":"kurnazlık / hilekarlık / beceriklilik","te":"Noun","tt":"İsim","de":"Skill in achieving one's ends by indirect or deceitful methods","dt":"Dolaylı veya hileli yöntemlerle hedeflere ulaşma becerisi","e1":"He relied on his craftiness to escape the trap.","e1t":"Tuzaktan kurtulmak için kurnazlığına güvendi.","e2":"Political craftiness.","e2t":"Siyasi kurnazlık."},{"w":"crag","tr":"sarp kaya / uçurum kenarı","te":"Noun","tt":"İsim","de":"A steep or rugged cliff or rock face","dt":"Dik veya engebeli uçurum veya kaya yüzeyi","e1":"The eagle nested on a high crag.","e1t":"Kartal yüksek bir sarp kayalığa yuva yaptı.","e2":"Craggy (adjective).","e2t":"Sarp / Kayalık."},{"w":"craven","tr":"korkak / ödlek","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Contemptibly lacking in courage; cowardly","dt":"Aşağılık derecede cesaretten yoksun; ödlek","e1":"A craven surrender.","e1t":"Ödlekçe bir teslimiyet.","e2":"He was too craven to speak the truth.","e2t":"Doğruyu söyleyemeyecek kadar korkaktı."},{"w":"creda","tr":"inançlar / ilkeler (çoğul)","te":"Noun","tt":"İsim","de":"A statement of the beliefs or aims which guide someone's actions","dt":"Birinin eylemlerine yön veren inanç veya hedeflerin beyanı","e1":"(Not: Genelde 'credo' veya 'creeds' kullanılır).","e1t":"","e2":"","e2t":""},{"w":"credence","tr":"inanma / güven / itimat","te":"Noun","tt":"İsim","de":"Belief in or acceptance of something as true","dt":"Bir şeyin doğruluğuna inanma veya kabul etme","e1":"To give credence to a rumor.","e1t":"Bir söylentiye inanmak (itimat etmek).","e2":"The letter lends credence to his story.","e2t":"Mektup onun hikayesine güvenilirlik katıyor."},{"w":"credulity","tr":"safdillik / her şeye inanma","te":"Noun","tt":"İsim","de":"A tendency to be too ready to believe that something is real or true","dt":"Bir şeyin gerçek veya doğru olduğuna çok çabuk inanma eğilimi","e1":"To take advantage of his credulity.","e1t":"Onun safdilliğinden faydalanmak.","e2":"Credulous (adjective).","e2t":"Saf / Her şeye inanan."},{"w":"crescendo","tr":"kademeli artış / kreşendo","te":"Noun/Adverb","tt":"A gradual increase in loudness in a piece of music; or a progressive increase in intensity","de":"Müzikte sesin kademeli olarak yükselmesi; veya şiddetin giderek artması","dt":"The noise rose to a crescendo.","e1":"Gürültü doruk noktasına çıktı (kreşendo yaptı).","e1t":"The campaign reached a crescendo just before the election.","e2":"Kampanya seçimden hemen önce zirveye ulaştı.","e2t":""},{"w":"crestfallen","tr":"boynu bükük / morali bozuk / hayal kırıklığına uğramış","te":"Adjective","tt":"Sıfat","de":"Sad and disappointed","dt":"Üzgün ve hayal kırıklığına uğramış","e1":"He looked crestfallen after losing the match.","e1t":"Maçı kaybettikten sonra boynu bükük (perişan) görünüyordu.","e2":"","e2t":""},{"w":"criteria","tr":"kriterler / ölçütler (çoğul)","te":"Noun","tt":"İsim","de":"Principles or standards by which something may be judged or decided","dt":"Bir şeyin yargılanabileceği veya karara bağlanabileceği ilkeler/standartlar","e1":"What are the criteria for selection?","e1t":"Seçim kriterleri (ölçütleri) nelerdir?","e2":"(Tekili: 'Criterion').","e2t":""},{"w":"crone","tr":"koca karı / çirkin yaşlı kadın","te":"Noun","tt":"İsim","de":"An ugly old woman","dt":"Çirkin yaşlı kadın","e1":"The old crone lived in a hut.","e1t":"Yaşlı koca karı bir kulübede yaşıyordu.","e2":"","e2t":""},{"w":"crotchety","tr":"huysuz / aksi / ters","te":"Adjective","tt":"Sıfat","de":"Irritable; bad","dt":"tempered","e1":"Çabuk sinirlenen; huysuz","e1t":"A crotchety old man.","e2":"Huysuz bir ihtiyar.","e2t":"He gets crotchety when he's tired."},{"w":"crucible","tr":"pota / zorlu sınav","te":"Noun","tt":"İsim","de":"A ceramic or metal container in which metals may be melted; or a situation of severe trial","dt":"Metallerin eritildiği seramik veya metal kap; veya ağır sınav/zorlu durum","e1":"To melt gold in a crucible.","e1t":"Altını potada eritmek.","e2":"The crucible of war.","e2t":"Savaşın zorlu sınavı (ateşi)."},{"w":"crypt","tr":"yer altı mezarı / mahzen (kilise altı)","te":"Noun","tt":"İsim","de":"An underground room or vault beneath a church, used as a chapel or burial place","dt":"Kilisenin altında şapel veya mezar olarak kullanılan yer altı odası","e1":"To be buried in the family crypt.","e1t":"Aile mahzenine gömülmek.","e2":"The dark, damp crypt of the cathedral.","e2t":"Katedralin karanlık ve nemli mahzeni."},{"w":"cubicle","tr":"bölme / hücre / kabin","te":"Noun","tt":"İsim","de":"A small partitioned","dt":"off area of a room","e1":"Bir odanın bölünmüş küçük alanı (kabin)","e1t":"An office cubicle.","e2":"Ofis bölmesi.","e2t":"A shower cubicle."},{"w":"culinary","tr":"yemek pişirme ile ilgili / mutfaka ait","te":"Adjective","tt":"Sıfat","de":"Of or for cooking","dt":"Yemek pişirme ile ilgili","e1":"Culinary skills.","e1t":"Yemek pişirme becerileri.","e2":"A culinary delight.","e2t":"Mutfak şaheseri (lezzet)."},{"w":"cull","tr":"seçip ayırmak / toplamak / (hayvan sayısını) azaltmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Select from a large quantity; or to reduce the population of a wild animal by selective slaughter","dt":"Büyük bir miktardan seçip almak; veya (zararlı/fazla) hayvanları seçip öldürerek sayıyı azaltmak","e1":"To cull data from various reports.","e1t":"Çeşitli raporlardan veri toplamak (ayırıp seçmek).","e2":"They cull the weak deer every winter.","e2t":"Her kış zayıf geyikleri (sürüyü sağlıklı tutmak için) ayırıp öldürürler."},{"w":"culminate","tr":"doruğa ulaşmak /","te":"ile sonuçlanmak","tt":"Verb","de":"Fiil","dt":"Reach a climax or point of highest development","e1":"Doruğa veya en yüksek gelişim noktasına ulaşmak","e1t":"The protests culminated in the resignation of the president.","e2":"Protestolar başkanın istifasıyla sonuçlandı (doruğa ulaştı).","e2t":"Culmination (noun)."},{"w":"culprit","tr":"suçlu / zanlı / neden (olumsuz şey için)","te":"Noun","tt":"İsim","de":"A person who is responsible for a crime or other misdeed; or the cause of a problem","dt":"Suçtan sorumlu kişi; veya bir sorunun nedeni","e1":"The police caught the culprit.","e1t":"Polis suçluyu yakaladı.","e2":"High sugar intake is the main culprit in tooth decay.","e2t":"Diş çürümesinin asıl nedeni (suçlusu) yüksek şeker tüketimidir."},{"w":"cultivatable","tr":"ekilebilir / işlenebilir","te":"Adjective","tt":"Sıfat","de":"(Of land) capable of being cultivated","dt":"(Toprak için) işlenmeye veya ekilmeye uygun","e1":"Cultivatable land.","e1t":"Ekilebilir arazi.","e2":"","e2t":""},{"w":"cultivated","tr":"ekilmiş / işlenmiş / eğitimli ve görgülü","te":"Adjective","tt":"Sıfat","de":"Prepared and used for raising crops; or refined and well educated","dt":"Mahsul yetiştirmek için hazırlanmış; veya nazik ve eğitimli","e1":"Cultivated fields.","e1t":"İşlenmiş tarlalar.","e2":"A cultivated man.","e2t":"Kültürlü (görgülü) bir adam."},{"w":"cupidity","tr":"açgözlülük / hırs / mal hırsı","te":"Noun","tt":"İsim","de":"Greed for money or possessions","dt":"Para veya mal mülk için duyulan aşırı hırs","e1":"He was motivated by cupidity.","e1t":"Açgözlülükle hareket etti.","e2":"The cupidity of the invaders.","e2t":"İstilacıların mal hırsı."},{"w":"curmudgeon","tr":"huysuz ihtiyar / aksi adam","te":"Noun","tt":"İsim","de":"A bad","dt":"tempered or surly person","e1":"Kötü huylu veya huysuz kişi","e1t":"A crusty old curmudgeon.","e2":"Aksi, huysuz bir ihtiyar.","e2t":""},{"w":"cursive","tr":"bitişik el yazısı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Written with the characters joined","dt":"Harfleri birbirine bağlı olarak yazılan","e1":"To write in cursive.","e1t":"Bitişik eğik yazı ile yazmak.","e2":"Cursive script.","e2t":"El yazısı."},{"w":"cursory","tr":"üstünkörü / aceleyle / dikkatsiz","te":"Adjective","tt":"Sıfat","de":"Hasty and therefore not thorough or detailed","dt":"Aceleyle yapılan ve bu nedenle detaylı olmayan","e1":"A cursory glance at the headlines.","e1t":"Manşetlere üstünkörü bir bakış.","e2":"To give the report a cursory examination.","e2t":"Raporu şöyle bir (yüzeysel) incelemek."},{"w":"cynic","tr":"kinik / her şeyin altında çıkar arayan / kötümser","te":"Noun","tt":"İsim","de":"A person who believes that people are motivated purely by self","dt":"interest","e1":"İnsanların sadece kendi çıkarlarıyla hareket ettiğine inanan kişi","e1t":"He's too much of a cynic to believe in true love.","e2":"Gerçek aşka inanmayacak kadar kinik (her şeye şüpheyle bakan) biri.","e2t":"Cynical (adjective)."},{"w":"cynosure","tr":"ilgi odağı / kutup yıldızı","te":"Noun","tt":"İsim","de":"A person or thing that is the center of attention or admiration","dt":"İlgi veya hayranlık odağı olan kişi/şey","e1":"She was the cynosure of all eyes.","e1t":"Tüm gözlerin odağıydı.","e2":"The cynosure of the party.","e2t":"Partinin yıldızı (ilgi odağı)."},{"w":"cytology","tr":"sitoloji / hücre bilimi","te":"Noun","tt":"İsim","de":"The branch of biology concerned with the structure and function of plant and animal cells","dt":"Bitki ve hayvan hücrelerinin yapısını ve işlevini inceleyen biyoloji dalı","e1":"Clinical cytology.","e1t":"Klinik sitoloji.","e2":"Cytologist (noun).","e2t":"Hücre bilimci."},{"w":"dais","tr":"kürsü / podyum / sekilik","te":"Noun","tt":"İsim","de":"A low platform for a lectern or a throne","dt":"Kürsü veya taht için ayrılmış alçak platform","e1":"The speaker stood on the dais.","e1t":"Konuşmacı kürsüde durdu.","e2":"A raised dais.","e2t":"Yükseltilmiş platform."},{"w":"dally","tr":"vakit öldürmek / oyalanmak / flört etmek","te":"Verb","tt":"Fiil","de":"Act or move slowly; or to have a casual romantic relationship","dt":"Yavaş hareket etmek (oyalanmak); veya ciddi olmayan romantik ilişki yaşamak","e1":"Stop dallying and get to work.","e1t":"Oyalanmayı bırak ve işe koyul.","e2":"To dally with someone's feelings.","e2t":"Birinin duygularıyla oynamak (eğlenmek)."},{"w":"dank","tr":"rutubetli / nemli ve soğuk","te":"Adjective","tt":"Sıfat","de":"Unpleasantly damp and cold","dt":"Nahoş bir şekilde nemli ve soğuk","e1":"A dank basement.","e1t":"Rutubetli (nemli) bir bodrum katı.","e2":"The dank air of the cave.","e2t":"Mağaranın rutubetli havası."},{"w":"dapper","tr":"şık / zarif / derli toplu (erkek)","te":"Adjective","tt":"Sıfat","de":"(Of a man) neat and trim in dress and appearance","dt":"(Erkek için) giyim kuşamında titiz ve şık","e1":"A dapper young man.","e1t":"Şık (derli toplu) bir genç adam.","e2":"He looked very dapper in his new suit.","e2t":"Yeni takım elbisesiyle çok zarif görünüyordu."},{"w":"dappled","tr":"alacalı / benekli / çilli","te":"Adjective","tt":"Sıfat","de":"Marked with spots or rounded patches of color or light","dt":"Beneklerle veya yuvarlak ışık/renk yamalarıyla kaplı","e1":"A dappled horse.","e1t":"Alacalı (benekli) bir at.","e2":"The dappled sunlight on the forest floor.","e2t":"Orman tabanındaki benek benek vuran güneş ışığı."},{"w":"daub","tr":"sıva / (boya vb.) çalmak / acemice boyamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Coat or smear (a surface) with a thick or sticky substance; or a smear of something","dt":"(Yüzeye) kalın veya yapışkan bir madde sürmek; veya acemice yapılmış boya/sıva","e1":"To daub mud on the walls.","e1t":"Duvarlara çamur sıvamak.","e2":"Graffiti was daubed on the statues.","e2t":"Heykellere (rastgele) grafitiler karalanmıştı."},{"w":"daunt","tr":"korkutmak / yıldırmak / gözünü korkutmak","te":"Verb","tt":"Fiil","de":"Make (someone) feel intimidated or apprehensive","dt":"Birini korkutmak veya endişelendirmek (yıldırmak)","e1":"She was not daunted by the difficult task.","e1t":"Zorlu görev onu yıldırmadı.","e2":"The mountain's height was daunting.","e2t":"Dağın yüksekliği göz korkutucuydu."},{"w":"dauntless","tr":"korkusuz / yılmaz / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"Showing fearlessness and determination","dt":"Korkusuzluk ve kararlılık gösteren","e1":"A dauntless explorer.","e1t":"Korkusuz bir kaşif.","e2":"Dauntless courage.","e2t":"Sarsılmaz cesaret."},{"w":"deadpan","tr":"ifadesiz (yüz/ses) / ciddi görünümlü (mizah)","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Deliberately impassive or expressionless","dt":"Kasten duygusuz veya ifadesiz","e1":"He delivered the joke in a deadpan voice.","e1t":"Şakayı son derece ciddi bir ses tonuyla (ifadesizce) yaptı.","e2":"A deadpan expression.","e2t":"Dümdüz (ifadesiz) bir yüz ifadesi."},{"w":"dearth","tr":"kıtlık / eksiklik / yokluk","te":"Noun","tt":"İsim","de":"A scarcity or lack of something","dt":"Bir şeyin kıtlığı veya eksikliği","e1":"A dearth of reliable information.","e1t":"Güvenilir bilgi eksikliği (kıtlığı).","e2":"There is a dearth of good teachers.","e2t":"İyi öğretmen bulmakta zorluk (yokluk) çekiliyor."},{"w":"debauch","tr":"ayartmak / yoldan çıkarmak / sefahat","te":"Verb/Noun","tt":"Fiil/İsim","de":"Corrupt the purity or luster of; or excessive indulgence in sensual pleasures","dt":"Saflığı bozmak; veya aşırı zevk düşkünlüğü (sefahat)","e1":"To debauch a young person's morals.","e1t":"Bir gencin ahlakını bozmak (yoldan çıkarmak).","e2":"Debauchery (noun).","e2t":"Sefahat / Ahlaki çöküş."},{"w":"debonair","tr":"nazik / şık / özgüvenli (erkek)","te":"Adjective","tt":"Sıfat","de":"(Of a man) confident, stylish, and charming","dt":"(Erkek için) kendinden emin, şık ve büyüleyici","e1":"A debonair gentleman.","e1t":"Nazik ve şık (beyefendi) bir adam.","e2":"He looked very debonair in his tuxedo.","e2t":"Smokin içinde çok karizmatik görünüyordu."},{"w":"debunk","tr":"(yalanını) ortaya çıkarmak / çürütmek","te":"Verb","tt":"Fiil","de":"Expose the falseness or hollowness of a myth, idea, or belief","dt":"Bir mitin, fikrin veya inancın sahteliğini ortaya koymak","e1":"To debunk a popular myth.","e1t":"Popüler bir efsaneyi çürütmek.","e2":"The study debunks the claims of the company.","e2t":"Çalışma şirketin iddialarını boşa çıkarıyor (çürütüyor)."},{"w":"debutante","tr":"sosyeteye yeni takdim edilen genç kız","te":"Noun","tt":"İsim","de":"An upper","dt":"class young woman making her first appearance in fashionable society","e1":"Seçkin toplum içine ilk kez çıkan (tanıtılan) genç hanım","e1t":"She was the season's most popular debutante.","e2":"Sezonun en popüler yeni yüzüydü.","e2t":""},{"w":"decadence","tr":"çöküş / yozlaşma / ahlaki gerileme","te":"Noun","tt":"İsim","de":"Moral or cultural decline as characterized by excessive indulgence in pleasure or luxury","dt":"Aşırı lüks ve zevke düşkünlükle karakterize edilen ahlaki veya kültürel çöküş","e1":"The decadence of modern society.","e1t":"Modern toplumun yozlaşması.","e2":"A period of luxury and decadence.","e2t":"Lüks ve ahlaki çöküş dönemi."},{"w":"decant","tr":"(şişeden başka kaba) aktarmak / süzmek","te":"Verb","tt":"Fiil","de":"Gradually pour (liquid, typically wine or a solution) from one container into another","dt":"Sıvıyı (genellikle şarap) tortusundan ayırmak için bir kaptan diğerine yavaşça dökmek","e1":"To decant wine before serving.","e1t":"Servis etmeden önce şarabı süzerek aktarmak.","e2":"The chemical was decanted into a flask.","e2t":"Kimyasal bir balona aktarıldı."},{"w":"decapitate","tr":"kafasını kesmek / idam etmek","te":"Verb","tt":"Fiil","de":"Cut off the head of (a person or animal)","dt":"Birinin veya bir hayvanın başını kesmek","e1":"He was decapitated for his crimes.","e1t":"Suçlarından dolayı idam edildi (baş vuruldu).","e2":"Decapitation (noun).","e2t":"Kafa kesme."},{"w":"decelerate","tr":"yavaşlamak / hızını kesmek","te":"Verb","tt":"Fiil","de":"Reduce the speed of; slow down","dt":"Hızı azaltmak; yavaşlamak","e1":"The car began to decelerate as it approached the corner.","e1t":"Araba köşeye yaklaşırken yavaşlamaya başladı.","e2":"Deceleration (noun).","e2t":"Yavaşlama."},{"w":"deciduous","tr":"yaprak döken / geçici","te":"Adjective","tt":"Sıfat","de":"(Of a tree or shrub) shedding its leaves annually","dt":"(Ağaç için) her yıl yaprak döken","e1":"Deciduous trees like oaks and maples.","e1t":"Meşe ve akçaağaç gibi yaprak döken ağaçlar.","e2":"Deciduous teeth (baby teeth).","e2t":"Süt dişleri (geçici dişler)."},{"w":"declivity","tr":"iniş / aşağı eğim / bayır","te":"Noun","tt":"İsim","de":"A downward slope","dt":"Aşağı doğru eğim, iniş","e1":"The road follows a steep declivity.","e1t":"Yol dik bir inişi takip ediyor. (Not: 'Acclivity'","e2":"yokuş","e2t":"kelimesinin zıttıdır)."},{"w":"décolleté / decollete","tr":"dekolte / düşük yakalı","te":"Adjective","tt":"Sıfat","de":"(Of a woman's dress) having a low neckline","dt":"(Kadın elbisesi için) düşük yakalı (göğüs kısmı açık)","e1":"A daring décolleté gown.","e1t":"Cesur bir dekolte elbise.","e2":"Decolletage (noun).","e2t":"Dekolte (boyun ve omuz bölgesi)."},{"w":"decomposition","tr":"ayrışma / çürüme / bozulma","te":"Noun","tt":"İsim","de":"The state or process of rotting; decay","dt":"Çürüme veya bozulma süreci","e1":"The decomposition of organic matter.","e1t":"Organik maddenin ayrışması (çürümesi).","e2":"Decomposition of water (chemistry).","e2t":"Suyun (bileşenlerine) ayrışması."},{"w":"decoy","tr":"tuzak / yem / aldatmaca","te":"Noun/Verb","tt":"İsim/Fiil","de":"A bird or dummy bird used to lure others into a trap; or someone used to distract","dt":"Tuzak kurmak için kullanılan (sahte) kuş veya nesne; veya dikkat dağıtıcı kişi","e1":"The police used a decoy to catch the thief.","e1t":"Polis hırsızı yakalamak için yem kullandı.","e2":"A decoy duck.","e2t":"Mühre (sahte ördek)."},{"w":"decrepit","tr":"elden ayaktan düşmüş / eskimiş / köhne","te":"Adjective","tt":"Sıfat","de":"(Of a person) elderly and infirm; or (of an object) worn out or ruined","dt":"(Kişi için) yaşlı ve bitkin; veya (nesne için) çok eskimiş ve bakımsız","e1":"A decrepit old man.","e1t":"Elden ayaktan düşmüş ihtiyar.","e2":"A decrepit building.","e2t":"Harabeye dönmüş (köhne) bina."},{"w":"deducible","tr":"sonuç olarak çıkarılabilir","te":"Adjective","tt":"Sıfat","de":"Able to be deduced (logically inferred)","dt":"(Mantıksal olarak) sonuç olarak çıkarılabilen","e1":"A deducible conclusion.","e1t":"Çıkarılabilecek (mantıklı) bir sonuç.","e2":"Deduce (verb).","e2t":"Sonuç çıkarmak."},{"w":"defalcate","tr":"zimmetine para geçirmek","te":"Verb","tt":"Fiil","de":"Embezzle (funds with which one has been entrusted)","dt":"(Kendine emanet edilen fonları) zimmetine geçirmek","e1":"He defalcated the company's money.","e1t":"Şirketin parasını zimmetine geçirdi.","e2":"Defalcation (noun).","e2t":"Zimmete para geçirme."},{"w":"defame","tr":"iftira atmak / lekelemek / adını lekelemek","te":"Verb","tt":"Fiil","de":"Damage the good reputation of someone; slander or libel","dt":"Birinin iyi itibarını zedelemek; kara çalmak","e1":"To defame a political opponent.","e1t":"Siyasi bir rakibe iftira atmak.","e2":"Defamation (noun).","e2t":"İftira / Karalama."},{"w":"defection","tr":"(taraf/parti) değiştirme / döneklik / firar","te":"Noun","tt":"İsim","de":"The desertion of one's country or cause in favor of an opposing one","dt":"Birinin ülkesini veya davasını bırakıp karşı tarafa geçmesi","e1":"A high","e1t":"level defection.","e2":"Üst düzey bir sığınma (taraf değiştirme).","e2t":"To defect from a party (verb)."},{"w":"defer","tr":"ertelemek / (başkasına) bırakmak / saygıdan uymak","te":"Verb","tt":"Fiil","de":"Put off (an action or event) to a later time; or to submit humbly to another's wish","dt":"Ertelemek; veya (saygıdan ötürü) birinin isteğine/kararına boyun eğmek (bırakmak)","e1":"To defer payment.","e1t":"Ödemeyi ertelemek.","e2":"I defer to your superior knowledge.","e2t":"Senin üstün bilgine saygı duyuyorum (kararı sana bırakıyorum)."},{"w":"deference","tr":"saygı / hürmet / boyun eğme","te":"Noun","tt":"İsim","de":"Humble submission and respect","dt":"Alçakgönüllü bir saygı ve uyum","e1":"Out of deference to her age.","e1t":"Yaşına duyulan saygıdan dolayı.","e2":"To treat someone with great deference.","e2t":"Birine büyük bir hürmetle davranmak."},{"w":"defile","tr":"kirletmek / lekelemek / geçit (dar)","te":"Verb/Noun","tt":"Fiil/İsim","de":"Sully, mar, or spoil; or a steep narrow gorge or pass","dt":"Kirletmek veya bozmak (lekelemek); veya sarp, dar geçit","e1":"To defile a sacred place.","e1t":"Kutsal bir yeri kirletmek.","e2":"The army passed through the mountain defile.","e2t":"Ordu dağ geçidinden geçti."},{"w":"definitive","tr":"kesin / nihai / en iyi (örnek)","te":"Adjective","tt":"Sıfat","de":"(Of a conclusion or agreement) done or reached decisively and with authority","dt":"Kesin ve nihai olarak varılmış (karar); veya bir şeyin en güvenilir örneği","e1":"A definitive answer.","e1t":"Kesin bir cevap.","e2":"The definitive biography of Einstein.","e2t":"Einstein hakkında yazılmış en kapsamlı (nihai) biyografi."},{"w":"deflect","tr":"yönünü değiştirmek / saptırmak / (soruyu) geçiştirmek","te":"Verb","tt":"Fiil","de":"Cause (something) to change direction by interposing something","dt":"Araya bir şey koyarak (bir şeyin) yönünü değiştirmek","e1":"The shield deflected the arrow.","e1t":"Kalkan oku saptırdı.","e2":"To deflect criticism.","e2t":"Eleştirileri savuşturmak (başka yöne çekmek)."},{"w":"deflower","tr":"(çiçeğini) koparmak / bekaretini bozmak / güzelliğini almak","te":"Verb","tt":"Fiil","de":"Deprive (a woman) of her virginity; or to strip of flowers","dt":"(Kadını) bekaretinden yoksun bırakmak; veya çiçeklerini yolmak","e1":"(Not: Edebi ve eski bir terimdir).","e1t":"","e2":"","e2t":""},{"w":"deformity","tr":"deformite / şekil bozukluğu / sakatlık","te":"Noun","tt":"İsim","de":"A physical blemish or distortion","dt":"Fiziksel kusur veya çarpıklık (biçim bozukluğu)","e1":"A facial deformity.","e1t":"Yüzdeki şekil bozukluğu.","e2":"Birth deformities.","e2t":"Doğuştan gelen sakatlıklar (bozukluklar)."},{"w":"defraud","tr":"dolandırmak / hakkını yemek","te":"Verb","tt":"Fiil","de":"Illegally obtain money from (someone) by deception","dt":"Birini aldatarak yasa dışı yolla parasını almak","e1":"To defraud the tax authorities.","e1t":"Vergi dairesini dolandırmak.","e2":"He was convicted of defrauding the company.","e2t":"Şirketi dolandırmaktan suçlu bulundu."},{"w":"defray","tr":"(masrafı) karşılamak / ödemek","te":"Verb","tt":"Fiil","de":"Provide money to pay (a cost or expense)","dt":"(Bir maliyeti veya masrafı) ödemek için para sağlamak","e1":"The company will defray your travel expenses.","e1t":"Şirket seyahat masraflarınızı karşılayacak.","e2":"To defray the costs.","e2t":"Maliyetleri üstlenmek."},{"w":"deify","tr":"tanrılaştırmak / ilahlaştırmak","te":"Verb","tt":"Fiil","de":"Worship or regard as a god","dt":"Tanrı olarak tapmak veya tanrı gibi görmek","e1":"To deify a leader.","e1t":"Bir lideri ilahlaştırmak.","e2":"The ancient Romans deified some of their emperors.","e2t":"Antik Romalılar bazı imparatorlarını tanrılaştırdılar."},{"w":"deign","tr":"tenezzül etmek / lütfetmek","te":"Verb","tt":"Fiil","de":"Do something that one considers to be beneath one's dignity","dt":"Kendi onuruna yakıştırmadığı (alçak gördüğü) bir şeyi yapmaya razı olmak","e1":"He didn't even deign to reply.","e1t":"Cevap vermeye tenezzül bile etmedi.","e2":"She deigned to join us for dinner.","e2t":"Lütfedip akşam yemeğinde bize katıldı."},{"w":"deity","tr":"ilah / tanrı / tanrıça","te":"Noun","tt":"İsim","de":"A god or goddess","dt":"Tanrı veya tanrıça","e1":"Ancient Greek deities.","e1t":"Antik Yunan tanrıları.","e2":"To worship a local deity.","e2t":"Yerel bir ilaha tapmak."},{"w":"delectable","tr":"lezzetli / nefis / çok hoş","te":"Adjective","tt":"Sıfat","de":"(Of food or drink) delicious; or extremely attractive","dt":"(Yiyecek/içecek için) lezzetli; veya son derece çekici","e1":"A delectable cheesecake.","e1t":"Nefis bir cheesecake.","e2":"The delectable smell of fresh bread.","e2t":"Taze ekmeğin o harika kokusu."},{"w":"deleterious","tr":"zararlı / nahoş etkisi olan","te":"Adjective","tt":"Sıfat","de":"Causing harm or damage","dt":"Zarar veya hasara neden olan","e1":"The deleterious effects of smoking on health.","e1t":"Sigara içmenin sağlık üzerindeki zararlı etkileri.","e2":"Deleterious to the environment.","e2t":"Çevre için zararlı."},{"w":"delirium","tr":"deliryum / sayıklama / kendinden geçme","te":"Noun","tt":"İsim","de":"An acutely disturbed state of mind that occurs in fever or intoxication","dt":"Ateşli hastalık veya zehirlenme sırasında görülen zihin bulanıklığı ve sayıklama hali","e1":"He was in a state of delirium.","e1t":"Sayıklama (deliryum) halindeydi.","e2":"Delirious (adjective).","e2t":"Sayıklayan / Çılgına dönmüş."},{"w":"delta","tr":"delta (nehir ağzı)","te":"Noun","tt":"İsim","de":"A triangular tract of sediment deposited at the mouth of a river","dt":"Nehir ağzında biriken üçgen şeklindeki alüvyon tabakası","e1":"The Nile Delta.","e1t":"Nil Deltası.","e2":"Fertile delta lands.","e2t":"Verimli delta toprakları."},{"w":"delude","tr":"aldatmak / kandırmak","te":"Verb","tt":"Fiil","de":"Impose a misleading belief upon (someone); deceive","dt":"Birini yanıltıcı bir inanca inandırmak; aldatmak","e1":"Don't delude yourself into thinking he loves you.","e1t":"Seni sevdiğini düşünerek kendini kandırma.","e2":"He deluded his followers.","e2t":"Takipçilerini aldattı."},{"w":"delusive","tr":"yanıltıcı / hayali / aldatıcı","te":"Adjective","tt":"Sıfat","de":"Giving a false or misleading impression","dt":"Yanlış veya yanıltıcı bir izlenim veren","e1":"Delusive hopes.","e1t":"Yanıltıcı (boş) umutlar.","e2":"A delusive sense of security.","e2t":"Aldatıcı bir güvenlik hissi."},{"w":"delve","tr":"derinlemesine araştırmak / (çanta vb.) karıştırmak","te":"Verb","tt":"Fiil","de":"Reach inside a receptacle and search for something; or to investigate a subject in detail","dt":"Bir kabın içini karıştırmak; veya bir konuyu derinlemesine incelemek","e1":"To delve into the past.","e1t":"Geçmişi deşmek (derinlemesine araştırmak).","e2":"She delved into her handbag for a pen.","e2t":"Kalem bulmak için çantasını karıştırdı."},{"w":"demagogue","tr":"demagog / halk avcısı","te":"Noun","tt":"İsim","de":"A political leader who seeks support by appealing to the desires and prejudices of ordinary people","dt":"Halkın arzu ve önyargılarına hitap ederek destek arayan siyasetçi","e1":"He was a gifted demagogue.","e1t":"Yetenekli bir demagogdu.","e2":"Demagoguery (noun).","e2t":"Demagoji / Laf cambazlığı."},{"w":"demerit","tr":"kusur / hata / ceza puanı","te":"Noun","tt":"İsim","de":"A fault or disadvantage; or a mark given to someone for a mistake","dt":"Kusur veya dezavantaj; veya bir hata için verilen eksi puan","e1":"The merits and demerits of the plan.","e1t":"Planın iyi ve kötü yanları (merit ve demeritleri).","e2":"To get a demerit in school.","e2t":"Okulda ceza puanı almak."},{"w":"demographic","tr":"demografik / nüfus yapısı ile ilgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the structure of populations","dt":"Nüfusun yapısı (yaş, cinsiyet vb.) ile ilgili","e1":"Demographic changes.","e1t":"Demografik değişiklikler.","e2":"A target demographic.","e2t":"Hedef kitle (demografik grup)."},{"w":"demolition","tr":"yıkım / imha","te":"Noun","tt":"İsim","de":"The action or process of demolishing or being demolished","dt":"Bir şeyi yıkma veya imha etme eylemi","e1":"The demolition of the old stadium.","e1t":"Eski stadyumun yıkımı.","e2":"Demolition crew.","e2t":"Yıkım ekibi."},{"w":"demoniac / demoniacal","tr":"şeytani / cin çarpmış gibi / kudurmuş","te":"Adjective","tt":"Sıfat","de":"Relating to or characteristic of a demon or demons; possessed","dt":"Şeytanla ilgili veya şeytanı andıran; cin çarpmış","e1":"A demoniacal laugh.","e1t":"Şeytani (korkunç) bir gülüş.","e2":"Demoniacal energy.","e2t":"Kudurmuşçasına (aşırı) bir enerji."},{"w":"demotic","tr":"halkın kullandığı dil / popüler","te":"Adjective","tt":"Sıfat","de":"Denoting or relating to the kind of language used by ordinary people","dt":"Sıradan insanların kullandığı (halk dili) ile ilgili","e1":"Demotic Greek.","e1t":"Halk Yunancası.","e2":"A demotic style of writing.","e2t":"Halkın anlayacağı sade bir yazı tarzı."},{"w":"demure","tr":"hanım hanımcık / ağırbaşlı / utangaç (kadın)","te":"Adjective","tt":"Sıfat","de":"(Of a woman or her behavior) reserved, modest, and shy","dt":"(Kadın veya davranışı için) ağırbaşlı, mütevazı ve utangaç","e1":"A demure young lady.","e1t":"Hanım hanımcık (çekingen) genç bir bayan.","e2":"She gave him a demure smile.","e2t":"Ona mahcup (utangaç) bir gülücük attı."},{"w":"denizen","tr":"sakin / bir yerde yaşayan canlı","te":"Noun","tt":"İsim","de":"An inhabitant or occupant of a particular place","dt":"Belirli bir yerin sakini veya orada yaşayan canlı","e1":"Denizens of the deep (sea animals).","e1t":"Derinliklerin sakinleri (deniz canlıları).","e2":"A denizen of the local bars.","e2t":"Yerel barların müdavimi (sakini)."},{"w":"denomination","tr":"mezhep / birim (para/ölçü) / adlandırma","te":"Noun","tt":"İsim","de":"A recognized autonomous branch of the Christian Church; or a value of a banknote","dt":"Hristiyan Kilisesi'nin tanınmış bir kolu (mezhep); veya banknotun değeri","e1":"Coins of different denominations.","e1t":"Farklı birimlerdeki madeni paralar (1 TL, 50 kr vb.).","e2":"Religious denominations.","e2t":"Dini mezhepler."},{"w":"denote","tr":"göstermek /","te":"e işaret etmek / anlamına gelmek","tt":"Verb","de":"Fiil","dt":"Be a sign of; indicate; or stand as a name or symbol for","e1":"Bir şeyin işareti olmak; veya simgesi/adı olmak","e1t":"A fever often denotes an infection.","e2":"Ateş genellikle bir enfeksiyona işaret eder.","e2t":"What does this symbol denote?"},{"w":"denouement","tr":"çözüm / sonuç (hikaye/oyun)","te":"Noun","tt":"İsim","de":"The final part of a play, movie, or narrative in which the strands of the plot are drawn together","dt":"Bir oyun, film veya hikayenin olay örgüsünün çözüldüğü final kısmı","e1":"The film's dramatic denouement.","e1t":"Filmin dramatik çözümü (finali).","e2":"The mystery reaches its denouement.","e2t":"Gizem sonucuna ulaşıyor."},{"w":"deplore","tr":"kınamak /","te":"e çok üzülmek / esefle karşılamak","tt":"Verb","de":"Fiil","dt":"Feel or express strong disapproval of","e1":"Şiddetle onaylamamak veya bir şeye çok üzülmek","e1t":"We deplore all forms of violence.","e2":"Şiddetin her türlüsünü kınatıyoruz (esefle karşılıyoruz).","e2t":"I deplore the loss of life."},{"w":"deploy","tr":"mevzilendirmek / konuşlandırmak / kullanmak (kaynak vb.)","te":"Verb","tt":"Fiil","de":"Move (troops) into position for military action; or utilize (resources)","dt":"Askerleri mevzilendirmek; veya kaynakları/becerileri kullanıma sokmak","e1":"To deploy troops along the border.","e1t":"Sınır boyunca asker konuşlandırmak.","e2":"To deploy new technology.","e2t":"Yeni teknolojiyi kullanıma sunmak (devreye almak)."},{"w":"deposition","tr":"görevden alma / yeminli ifade / tortu / birikme","te":"Noun","tt":"İsim","de":"The action of deposing someone, especially a monarch; or a process of sediment settling","dt":"Birini (özellikle bir hükümdarı) görevden alma; veya tortu birikmesi","e1":"The deposition of the king.","e1t":"Kralın tahttan indirilmesi.","e2":"To give a legal deposition.","e2t":"Yasal ifade vermek."},{"w":"depravity","tr":"ahlaki bozukluk / yozlaşma / sefalet","te":"Noun","tt":"İsim","de":"Moral corruption; wickedness","dt":"Ahlaki çöküş; kötülük","e1":"A life of depravity.","e1t":"Ahlaksızlık (yozlaşma) dolu bir hayat.","e2":"Depraved (adjective).","e2t":"Ahlaksız / Yozlaşmış."},{"w":"depreciate","tr":"değeri düşmek / küçümsemek / amortisman ayırmak","te":"Verb","tt":"Fiil","de":"Diminish in value over a period of time; or disparage","dt":"Zamanla değer kaybetmek; veya birini/bir şeyi küçümsemek","e1":"The car depreciates quickly.","e1t":"Araba hızla değer kaybeder.","e2":"To depreciate someone's efforts.","e2t":"Birinin çabalarını küçümsemek."},{"w":"depredation","tr":"yağmalama / zarar verme / tahribat","te":"Noun","tt":"İsim","de":"An act of attacking or plundering","dt":"Yağmalama veya saldırı eylemi","e1":"To protect the forest from the depredations of loggers.","e1t":"Ormanı oduncuların tahribatından (zararından) korumak.","e2":"Depredations of war.","e2t":"Savaşın getirdiği yıkımlar."},{"w":"deprive","tr":"yoksun bırakmak / mahrum etmek","te":"Verb","tt":"Fiil","de":"Deny (a person or place) the possession or use of something","dt":"Birini bir şeyin sahipliğinden veya kullanımından yoksun bırakmak","e1":"To deprive someone of their rights.","e1t":"Birini haklarından mahrum etmek.","e2":"Sleep","e2t":"deprived."},{"w":"derange","tr":"delirtmek / akıl sağlığını bozmak / düzenini bozmak","te":"Verb","tt":"Fiil","de":"Make (someone) insane; or throw into confusion","dt":"Birini akli dengesini bozacak kadar sarsmak; veya düzeni bozmak","e1":"The tragedy deranged his mind.","e1t":"Trajedi onun akıl sağlığını bozdu.","e2":"A deranged person.","e2t":"Akli dengesi bozuk (meczup) kişi."},{"w":"derisive","tr":"alaycı / küçümseyen","te":"Adjective","tt":"Sıfat","de":"Expressing contempt or ridicule","dt":"Aşağılama veya alay ifade eden","e1":"A derisive laugh.","e1t":"Alaycı bir gülüş.","e2":"Derisive comments.","e2t":"Küçümseyen yorumlar."},{"w":"derivation","tr":"türetme / köken / kaynak","te":"Noun","tt":"İsim","de":"The obtaining or developing of something from a source or origin","dt":"Bir kaynaktan bir şey elde etme veya geliştirme süreci","e1":"The derivation of a word.","e1t":"Bir kelimenin kökeni (türetilmesi).","e2":"Of French derivation.","e2t":"Fransız kökenli."},{"w":"dermatologist","tr":"dermatolog / cildiye uzmanı","te":"Noun","tt":"İsim","de":"A medical practitioner qualified to diagnose and treat skin disorders","dt":"Cilt hastalıklarını teşhis ve tedavi eden uzman doktor","e1":"I need to see a dermatologist for my rash.","e1t":"Kaşıntım için bir dermatoloğa görünmem gerekiyor.","e2":"Dermatology (noun).","e2t":"Dermatoloji."},{"w":"descant","tr":"ayrıntılı konuşmak / şarkı söylemek / üst ses","te":"Verb/Noun","tt":"Fiil/İsim","de":"Talk tediously or at length; or an independent treble melody sung or played above a basic melody","dt":"Uzun uzadıya (ayrıntılı) konuşmak; veya temel melodinin üzerindeki tiz melodi","e1":"To descant on a favorite subject.","e1t":"Sevdiği bir konu üzerinde uzun uzun konuşmak.","e2":"A soprano descant.","e2t":"Soprano üst sesi."},{"w":"descry","tr":"uzaktan görmek / seçmek / fark etmek","te":"Verb","tt":"Fiil","de":"Catch sight of (something distant)","dt":"(Uzak bir şeyi) gözle seçmek, fark etmek","e1":"We finally descried the shore through the mist.","e1t":"Sislerin arasından kıyıyı nihayet seçebildik.","e2":"","e2t":""},{"w":"desperado","tr":"desperado / kanun kaçağı / gözü dönmüş suçlu","te":"Noun","tt":"İsim","de":"A desperate or reckless person, especially a criminal","dt":"Gözü pek, tehlikeli ve kanun tanımaz kişi (özellikle suçlu)","e1":"Tales of wild west desperadoes.","e1t":"Vahşi Batı'nın kanun kaçakları hakkındaki hikayeler.","e2":"","e2t":""},{"w":"despicable","tr":"aşağılık / iğrenç / nefret uyandırıcı","te":"Adjective","tt":"Sıfat","de":"Deserving hatred and contempt","dt":"Nefret ve aşağılamayı hak eden","e1":"A despicable crime.","e1t":"Aşağılık (iğrenç) bir suç.","e2":"Despicable behavior.","e2t":"Nefret uyandırıcı davranış."},{"w":"despoil","tr":"yağmalamak / soymak / mahrum etmek","te":"Verb","tt":"Fiil","de":"Steal or violently remove valuable or attractive possessions from; plunder","dt":"Değerli şeyleri zorla veya yağmayla almak; soymak","e1":"To despoil a village of its treasures.","e1t":"Bir köyü hazinelerinden mahrum bırakmak (yağmalamak).","e2":"The landscape was despoiled by strip mining.","e2t":"Doğa, madencilik faaliyetleri ile tahrip edildi (yağmalandı)."},{"w":"detached","tr":"ayrı / müstakil / tarafsız / ilgisiz","te":"Adjective","tt":"Sıfat","de":"Separate or disconnected; or aloof and objective","dt":"Ayrı veya bağlantısız; veya mesafeli ve tarafsız","e1":"A detached house.","e1t":"Müstakil ev.","e2":"To observe with a detached interest.","e2t":"Tarafsız (objektif) bir ilgiyle gözlemlemek."},{"w":"detergent","tr":"deterjan / temizleyici","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A water","dt":"soluble cleansing agent which combines with impurities and dirt to make them more soluble","e1":"Kiri ve safsızlıkları çözerek temizleyen, suda çözünür madde","e1t":"Synthetic detergents.","e2":"Sentetik deterjanlar.","e2t":"Laundry detergent."},{"w":"determinate","tr":"belirli / kesin / sınırları olan","te":"Adjective","tt":"Sıfat","de":"Having fixed limits; definite","dt":"Sabit sınırları olan; kesin","e1":"A determinate number of participants.","e1t":"Belirli bir katılımcı sayısı.","e2":"Determinate growth (biology).","e2t":"Sınırlı (belirli bir noktada duran) büyüme."},{"w":"deterrent","tr":"caydırıcı / engelleyici","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A thing that discourages or is intended to discourage someone from doing something","dt":"Birini bir şeyi yapmaktan vazgeçiren veya vazgeçirmeyi amaçlayan şey","e1":"The nuclear deterrent.","e1t":"Nükleer caydırıcılık (silahı).","e2":"High fines serve as a deterrent to speeding.","e2t":"Yüksek para cezaları hız yapmaya karşı caydırıcıdır."},{"w":"detonate","tr":"patlatmak / infilak etmek","te":"Verb","tt":"Fiil","de":"Explode or cause to explode","dt":"Patlamak veya patlatmak","e1":"To detonate a bomb.","e1t":"Bombayı patlatmak.","e2":"The device detonated prematurely.","e2t":"Düzenek vaktinden önce infilak etti."},{"w":"detraction","tr":"karalama / iftira / değerini düşürme","te":"Noun","tt":"İsim","de":"The act of taking away from the reputation or worth of someone or something","dt":"Birinin itibarından veya bir şeyin değerinden çalma (kötüleme) eylemi","e1":"To engage in detraction of a rival's success.","e1t":"Bir rakibin başarısını gölgelemeye (karalamaya) çalışmak.","e2":"Detractor (noun).","e2t":"Kötüleyen kişi / Muhalif."},{"w":"deviate","tr":"sapmak / yönünü değiştirmek","te":"Verb","tt":"Fiil","de":"Depart from an established course or standards","dt":"Belirlenmiş bir rotadan veya standartlardan sapmak","e1":"To deviate from the plan.","e1t":"Plandan sapmak.","e2":"Never deviate from the truth.","e2t":"Doğruluktan asla ayrılma (sapma)."},{"w":"devolve","tr":"devretmek / gerilemek / (sorumluluk) geçmek","te":"Verb","tt":"Fiil","de":"Transfer or delegate (power) to a lower level; or to degenerate","dt":"Gücü veya yetkiyi daha alt bir düzeye devretmek; veya (daha kötü bir duruma) evrilmek/gerilemek","e1":"The power was devolved to regional assemblies.","e1t":"Yetki bölgesel meclislere devredildi.","e2":"The conversation devolved into a fight.","e2t":"Konuşma bir kavgaya dönüştü (geriledi)."},{"w":"devotee","tr":"tutkun / hayran / mürid","te":"Noun","tt":"İsim","de":"A person who is very interested in and enthusiastic about someone or something","dt":"Birine veya bir şeye karşı çok ilgili ve hevesli olan kişi","e1":"A devotee of classical music.","e1t":"Klasik müzik tutkunu.","e2":"Devotees of a religious leader.","e2t":"Bir dini liderin müridleri (bağlıları)."},{"w":"dexterous / dextrous","tr":"becerikli / el çabukluğu olan / mahir","te":"Adjective","tt":"Sıfat","de":"Showing or having skill, especially with the hands","dt":"Özellikle ellerini kullanmada beceri gösteren (mahir)","e1":"Dexterous fingers.","e1t":"Becerikli parmaklar.","e2":"A dexterous move.","e2t":"Ustaca bir hamle."},{"w":"diabolical / diabolic","tr":"şeytani / berbat / çok kötü","te":"Adjective","tt":"Sıfat","de":"Characteristic of the Devil, or so evil as to recall the Devil; or disgracefully bad","dt":"Şeytana özgü veya şeytanı çağrıştıracak kadar kötü/zalim; veya berbat","e1":"A diabolical plot.","e1t":"Şeytani bir plan.","e2":"The traffic was diabolical.","e2t":"Trafik berbattı (çok kötüydü)."},{"w":"diadem","tr":"diadem / taç","te":"Noun","tt":"İsim","de":"A jeweled crown or headband worn as a symbol of sovereignty","dt":"Hükümdarlık sembolü olarak takılan mücevherli taç veya başlık","e1":"A diadem of diamonds and rubies.","e1t":"Elmas ve yakutlardan oluşan bir diadem.","e2":"","e2t":""},{"w":"diagnosis","tr":"teşhis / tanı","te":"Noun","tt":"İsim","de":"The identification of the nature of an illness or other problem by examination of the symptoms","dt":"Belirtilerin incelenmesiyle bir hastalığın veya sorunun doğasının belirlenmesi","e1":"To make a diagnosis.","e1t":"Teşhis koymak.","e2":"A preliminary diagnosis.","e2t":"Ön teşhis."},{"w":"dialectical / dialectic","tr":"diyalektik / akıl yürütme ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the logical discussion of ideas and opinions","dt":"Fikir ve görüşlerin mantıksal tartışmasıyla ilgili","e1":"Dialectical materialism.","e1t":"Diyalektik materyalizm.","e2":"A dialectical approach.","e2t":"Diyalektik bir yaklaşım."},{"w":"diaphanous","tr":"şeffaf / incecik / saydam (kumaş)","te":"Adjective","tt":"Sıfat","de":"(Especially of fabric) light, delicate, and translucent","dt":"(Özellikle kumaş için) hafif, ince ve ışık geçiren","e1":"A diaphanous silk scarf.","e1t":"İncecik (şeffaf) ipek bir eşarp.","e2":"Diaphanous wings of a dragonfly.","e2t":"Bir yusufçuğun şeffaf kanatları."},{"w":"dictum","tr":"vecize / söz / resmi beyan","te":"Noun","tt":"İsim","de":"A formal pronouncement from an authoritative source; or a short statement that expresses a general truth","dt":"Yetkili bir kaynaktan gelen resmi ifade; veya genel bir gerçeği ifade eden kısa söz","e1":"The old dictum \"knowledge is power\".","e1t":"Eski bir vecize: \"Bilgi güçtür.\"","e2":"A judicial dictum.","e2t":"Hukuki bir beyan."},{"w":"diffidence","tr":"çekingenlik / özgüvensizlik","te":"Noun","tt":"İsim","de":"Modesty or shyness resulting from a lack of self","dt":"confidence","e1":"Özgüven eksikliğinden kaynaklanan mahcubiyet veya çekingenlik","e1t":"She overcome her natural diffidence.","e2":"Doğal çekingenliğini yendi.","e2t":"Diffident (adjective)."},{"w":"diffuse","tr":"yaymak / dağılmak / uzun ve dağınık","te":"Verb/Adjective","tt":"Spread or cause to spread over a wide area or among a large number of people; or lacking clarity or conciseness","de":"Geniş bir alana yaymak veya yayılmak; veya dağınık (net olmayan)","dt":"Diffuse light.","e1":"Dağınık (homojen) ışık.","e1t":"To diffuse knowledge.","e2":"Bilgiyi yaymak.","e2t":""},{"w":"digression","tr":"konudan sapma / ayrıntı","te":"Noun","tt":"İsim","de":"A temporary departure from the main subject in speech or writing","dt":"Konuşma veya yazıda ana konudan geçici olarak uzaklaşma","e1":"Please excuse this brief digression.","e1t":"Lütfen konudan bu kısa sapmamı mazur görün.","e2":"Digress (verb).","e2t":"Konudan sapmak."},{"w":"dilate","tr":"genişlemek / büyümek (göz bebeği vb.) / uzun uzadıya anlatmak","te":"Verb","tt":"Fiil","de":"Make or become wider, larger, or more open; or to speak or write at length on a subject","dt":"Genişlemek, büyümek veya açılmak; veya bir konuyu uzun uzun anlatmak","e1":"Her pupils dilated in the dark.","e1t":"Karanlıkta göz bebekleri büyüdü.","e2":"To dilate on a favorite topic.","e2t":"Sevdiği bir konuyu uzun uzun anlatmak."},{"w":"dilatory","tr":"yavaş / geciktirici / oyalanan","te":"Adjective","tt":"Sıfat","de":"Slow to act; intended to cause delay","dt":"Hareket etmekte yavaş; gecikmeye neden olan","e1":"Dilatory tactics.","e1t":"Geciktirme taktikleri.","e2":"He was dilatory in paying his bills.","e2t":"Faturalarını ödemede çok yavaştı (gecikiyordu)."},{"w":"dilettante","tr":"amatör / hevesli (yüzeysel) / sanat meraklısı","te":"Noun","tt":"İsim","de":"A person who cultivates an area of interest, such as the arts, without real commitment or knowledge","dt":"Bir ilgi alanıyla (sanat vb.) gerçek bir derinlik veya bilgi olmaksızın, yüzeysel olarak uğraşan kişi","e1":"He is a mere dilettante in the world of opera.","e1t":"Opera dünyasında o sadece bir heveslidir (yüzeysel meraklı).","e2":"A dilettante approach to science.","e2t":"Bilime amatörce (derinleşmeden) yaklaşım."},{"w":"diligence","tr":"çalışkanlık / özen / sebat","te":"Noun","tt":"İsim","de":"Careful and persistent work or effort","dt":"Dikkatli, sürekli çalışma veya çaba","e1":"Success is the result of hard work and diligence.","e1t":"Başarı, sıkı çalışma ve sebatın sonucudur.","e2":"Due diligence (legal).","e2t":"Durum tespiti (gerekli özenin gösterilmesi)."},{"w":"dilute","tr":"seyreltmek / sulandırmak / hafifletmek","te":"Verb/Adjective","tt":"Make (a liquid) thinner or weaker by adding water or another solvent; or to weaken the force of","de":"Bir sıvıya su veya başka çözücü ekleyerek inceltmek; veya bir gücü/etkiyi zayıflatmak","dt":"To dilute the paint with turpentine.","e1":"Boyayı tinerle seyreltmek.","e1t":"The news diluted the impact of the victory.","e2":"Haberler, zaferin etkisini hafifletti.","e2t":""},{"w":"diminution","tr":"azalma / eksilme / küçülme","te":"Noun","tt":"İsim","de":"A reduction in the size, extent, or importance of something","dt":"Bir şeyin boyutu, kapsamı veya önemindeki azalma","e1":"A permanent diminution of his authority.","e1t":"Yetkisinin kalıcı olarak azalması.","e2":"No diminution of quality.","e2t":"Kalitede hiçbir eksilme yok."},{"w":"dint","tr":"güç / etki / darbe izi","te":"Noun","tt":"İsim","de":"An impression or hollow in a surface; or force/power (usually in \"by dint of\")","dt":"Bir yüzeydeki çöküntü veya iz; veya güç/sayesinde","e1":"By dint of hard work.","e1t":"Sıkı çalışma sayesinde (gücüyle).","e2":"To make a dint in the metal.","e2t":"Metalde bir çöküntü (iz) oluşturmak."},{"w":"diorama","tr":"diyorama / üç boyutlu maket","te":"Noun","tt":"İsim","de":"A model representing a scene with three","dt":"dimensional figures","e1":"Üç boyutlu figürlerle bir sahneyi temsil eden model","e1t":"A museum diorama of a prehistoric village.","e2":"Bir tarih öncesi köyün müze diyoraması.","e2t":"To build a diorama for the project."},{"w":"dirge","tr":"ağıt / cenaze marşı","te":"Noun","tt":"İsim","de":"A lament for the dead, especially one forming part of a funeral rite","dt":"Ölüler için yakılan ağıt; cenaze marşı","e1":"The mournful dirge played at the funeral.","e1t":"Cenazede çalınan kederli marş.","e2":"His latest album sounds like a dirge.","e2t":"Son albümü bir ağıt gibi tınlıyor."},{"w":"disabuse","tr":"(birini) yanlış bir düşünceden kurtarmak / gerçeği göstermek","te":"Verb","tt":"Fiil","de":"Persuade (someone) that an idea or belief is mistaken","dt":"Birini, bir fikrinin veya inancının yanlış olduğuna ikna etmek","e1":"To disabuse someone of a notion.","e1t":"Birini bir düşüncesinden (yanılgısından) vazgeçirmek.","e2":"I must disabuse you of that idea.","e2t":"Seni bu fikirden kurtarmalıyım (yanlışını düzeltmeliyim)."},{"w":"disaffected","tr":"memnuniyetsiz / soğumuş / düzene küskün","te":"Adjective","tt":"Sıfat","de":"Dissatisfied with the people in authority and no longer willing to support them","dt":"Otoriteye karşı memnuniyetsiz ve artık onları desteklemeyen","e1":"Disaffected youth.","e1t":"Topluma küskün (memnuniyetsiz) gençler.","e2":"A group of disaffected voters.","e2t":"Düzenden soğumuş bir grup seçmen."},{"w":"disapprobation","tr":"onaylamama / kınama / hoşnutsuzluk","te":"Noun","tt":"İsim","de":"Strong disapproval, typically on moral grounds","dt":"Genellikle ahlaki nedenlerle duyulan güçlü hoşnutsuzluk veya kınama","e1":"To face public disapprobation.","e1t":"Halkın kınamasıyla karşılaşmak.","e2":"She feared her father's disapprobation.","e2t":"Babasının onaylamamasından korkuyordu."},{"w":"disarray","tr":"düzensizlik / darmadağınık hal / kargaşa","te":"Noun/Verb","tt":"İsim/Fiil","de":"A state of disorganization or untidiness","dt":"Düzensizlik veya dağınıklık durumu","e1":"The room was in total disarray.","e1t":"Oda tam bir dağınıklık içindeydi.","e2":"The enemy's retreat was in disarray.","e2t":"Düşmanın geri çekilmesi kargaşa içindeydi."},{"w":"disavowal","tr":"inkar / reddetme / üstlenmeme","te":"Noun","tt":"İsim","de":"A denial of any responsibility or support for something","dt":"Bir şey için sorumluluğu veya desteği reddetme/inkar etme","e1":"A formal disavowal of the treaty.","e1t":"Antlaşmanın resmen reddi.","e2":"His disavowal of his earlier claims.","e2t":"Önceki iddialarını inkar etmesi."},{"w":"discernible","tr":"fark edilebilir / görülebilir / seçilebilir","te":"Adjective","tt":"Sıfat","de":"Able to be discerned; perceptible","dt":"Fark edilebilen; seçilebilen","e1":"No discernible improvement in the patient's condition.","e1t":"Hastanın durumunda fark edilebilir bir iyileşme yok.","e2":"A discernible difference.","e2t":"Görülebilir bir fark."},{"w":"discerning","tr":"ferasetli / ayırt edebilen / zevkli","te":"Adjective","tt":"Sıfat","de":"Having or showing good judgment","dt":"İyi muhakeme yeteneği olan; ince eleyip sık dokuyan","e1":"A discerning critic.","e1t":"Seçici (usta) bir eleştirmen.","e2":"For the discerning traveler.","e2t":"Zevk sahibi (ne istediğini bilen) gezgin için."},{"w":"disclaim","tr":"reddetmek / feragat etmek / sorumluluk üstlenmemek","te":"Verb","tt":"Fiil","de":"Refuse to acknowledge; deny","dt":"Kabul etmeyi reddetmek; inkar etmek","e1":"The company disclaims all responsibility for the accident.","e1t":"Şirket kazayla ilgili tüm sorumluluğu reddeder.","e2":"To disclaim a right.","e2t":"Bir haktan feragat etmek."},{"w":"disclose","tr":"açığa vurmak / ifşa etmek / açıklamak","te":"Verb","tt":"Fiil","de":"Make (secret or new information) known","dt":"(Gizli veya yeni bilgiyi) duyurmak veya ortaya çıkarmak","e1":"To disclose confidential information.","e1t":"Gizli bilgileri ifşa etmek.","e2":"He refused to disclose his sources.","e2t":"Kaynaklarını açıklamayı reddetti."},{"w":"discomfit","tr":"huzursuz etmek / mahcup etmek / planını bozmak","te":"Verb","tt":"Fiil","de":"Make (someone) feel uneasy or embarrassed","dt":"Birini huzursuz veya mahcup hissettirmek","e1":"He was discomfited by the question.","e1t":"Soru karşısında ne yapacağını şaşırdı (huzursuz oldu).","e2":"Discomfiture (noun).","e2t":"Mahcubiyet / Rahatsızlık."},{"w":"disconcert","tr":"huzursuz etmek / şaşırtmak / dengesini bozmak","te":"Verb","tt":"Fiil","de":"Disturb the composure of; unsettle","dt":"Birinin soğukkanlılığını veya dengesini bozmak","e1":"The bad news disconcerted him.","e1t":"Kötü haberler onun dengesini bozdu (huzursuz etti).","e2":"A disconcerting silence.","e2t":"Rahatsız edici bir sessizlik."},{"w":"disconsolate","tr":"kederli / teselli edilemez / mutsuz","te":"Adjective","tt":"Sıfat","de":"Without consolation or comfort; unhappy","dt":"Teselli bulamayan; çok mutsuz","e1":"The disconsolate players left the field.","e1t":"Kederli oyuncular sahayı terk etti.","e2":"He was disconsolate after the death of his dog.","e2t":"Köpeğinin ölümünden sonra teselli edilemez haldeydi."},{"w":"discord","tr":"anlaşmazlık / uyumsuzluk / nifak / kakofoni","te":"Noun/Verb","tt":"İsim/Fiil","de":"Lack of agreement or harmony; or (music) lack of harmony between notes","dt":"Anlaşmazlık veya uyum eksikliği; veya (müzik) ses uyumsuzluğu","e1":"Civil discord.","e1t":"İç huzursuzluk (anlaşmazlık).","e2":"To sow seeds of discord.","e2t":"Nifak tohumları ekmek."},{"w":"discordant","tr":"uyumsuz / aykırı / kulak tırmalayan","te":"Adjective","tt":"Sıfat","de":"Disagreeing or incongruous; or (of sounds) harsh and jarring","dt":"Uyumsuz veya aykırı; veya (ses için) tırmalayan","e1":"Discordant opinions.","e1t":"Birbiriyle çelişen (uyumsuz) fikirler.","e2":"A discordant note.","e2t":"Uyumsuz (yanlış) bir nota."},{"w":"discredit","tr":"itibarsızlaştırmak / güvenini sarsmak / itibar kaybı","te":"Verb/Noun","tt":"Fiil/İsim","de":"Harm the good reputation of; or cause to be disbelieved","dt":"İtibarına zarar vermek; veya güvenirliğini sarsmak","e1":"To discredit a witness.","e1t":"Bir tanığı itibarsızlaştırmak.","e2":"The theory has been thoroughly discredited.","e2t":"Teori tamamen çürütüldü (itibarı sarsıldı)."},{"w":"discrete","tr":"ayrı / ayrık / münferit","te":"Adjective","tt":"Sıfat","de":"Individually separate and distinct","dt":"Bireysel olarak ayrı ve belirgin","e1":"Discrete units.","e1t":"Ayrık birimler.","e2":"The process can be broken down into discrete steps.","e2t":"Süreç münferit (ayrı) adımlara bölünebilir. (Not: 'Discreet'"},{"w":"disembark","tr":"gemiden/uçaktan inmek","te":"Verb","tt":"Fiil","de":"Leave a ship, aircraft, or other vehicle","dt":"Gemiden, uçaktan veya başka bir araçtan inmek","e1":"The passengers disembarked at the port.","e1t":"Yolcular limanda gemiden indiler.","e2":"Disembarkation (noun).","e2t":"Karaya çıkış / İniş."},{"w":"disenfranchise","tr":"oy hakkından mahrum etmek / haklarını elinden almak","te":"Verb","tt":"Fiil","de":"Deprive (someone) of the right to vote; or deprive of a right or privilege","dt":"(Birini) oy kullanma hakkından veya bir haktan mahrum bırakmak","e1":"Disenfranchised voters.","e1t":"Oy hakkı elinden alınmış seçmenler.","e2":"Poverty disenfranchises people.","e2t":"Yoksulluk insanları haklarından (toplumdan) koparır."},{"w":"disgorge","tr":"kusmak / dışarı boşaltmak / (zorla) geri vermek","te":"Verb","tt":"Fiil","de":"Cause to pour out; or to yield (something), typically under pressure","dt":"Dışarı akıtmak; veya (genellikle baskı altında) bir şeyi teslim etmek/çıkarmak","e1":"The volcano disgorged lava.","e1t":"Yanardağ lav püskürttü (kustu).","e2":"To disgorge illegal profits.","e2t":"Yasa dışı kârları geri vermek (iade etmek)."},{"w":"disgrace","tr":"rezalet / utanç / itibarını lekelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Loss of reputation or respect as the result of a dishonorable action","dt":"Onur kırıcı bir eylem sonucu itibar kaybı (utanç)","e1":"To be in disgrace.","e1t":"Gözden düşmek / Rezalet içinde olmak.","e2":"You are a disgrace to this family.","e2t":"Sen bu aile için bir utanç kaynağısın."},{"w":"disgruntled","tr":"memnuniyetsiz / küskün / hırçın","te":"Adjective","tt":"Sıfat","de":"Angry or dissatisfied","dt":"Öfkeli veya memnuniyetsiz","e1":"Disgruntled employees.","e1t":"Memnuniyetsiz çalışanlar.","e2":"He left the meeting feeling disgruntled.","e2t":"Toplantıdan küskün bir halde ayrıldı."},{"w":"disinclination","tr":"isteksizlik / gönülsüzlük","te":"Noun","tt":"İsim","de":"A reluctance or lack of enthusiasm","dt":"Gönülsüzlük veya heves eksikliği","e1":"A disinclination to work.","e1t":"Çalışmaya karşı isteksizlik.","e2":"Disinclined (adjective).","e2t":"İsteksiz."},{"w":"disinter","tr":"(mezardan) çıkarmak / ortaya çıkarmak","te":"Verb","tt":"Fiil","de":"Dig up (something that has been buried, especially a corpse)","dt":"Gömülü bir şeyi (özellikle cesedi) kazıp çıkarmak","e1":"The body was disinterred for an autopsy.","e1t":"Ceset otopsi için mezardan çıkarıldı.","e2":"To disinter old facts.","e2t":"Eski gerçekleri gün yüzüne çıkarmak. (Not: 'Inter'"},{"w":"disinterested","tr":"tarafsız / çıkarsız / ilgisiz (yanlış kullanım)","te":"Adjective","tt":"Sıfat","de":"Not influenced by considerations of personal advantage; unbiased","dt":"Kişisel çıkar gütmeyen; tarafsız","e1":"A disinterested observer.","e1t":"Tarafsız bir gözlemci.","e2":"Disinterested advice.","e2t":"Çıkarsız (objektif) tavsiye. (Not: 'Uninterested'"},{"w":"disjointed","tr":"kopuk / tutarsız / eklemi çıkmış","te":"Adjective","tt":"Sıfat","de":"Lacking a coherent sequence or connection","dt":"Tutarlı bir dizilim veya bağlantıdan yoksun","e1":"A disjointed speech.","e1t":"Kopuk (bağlantısız) bir konuşma.","e2":"Disjointed thoughts.","e2t":"Darmadağınık (tutarsız) düşünceler."},{"w":"dismal","tr":"kasvetli / iç karartıcı / çok kötü","te":"Adjective","tt":"Sıfat","de":"Depressing; dreary; or pitifully or disgracefully bad","dt":"Depresif; kasvetli; veya iç karartıcı derecede kötü","e1":"Dismal weather.","e1t":"Kasvetli (kapalı) hava.","e2":"A dismal failure.","e2t":"İç karartıcı bir başarısızlık."},{"w":"dismember","tr":"uzuvlarını kesmek / (toprak vb.) bölmek","te":"Verb","tt":"Fiil","de":"Cut off the limbs of (a person or animal); or partition or divide up","dt":"Birinin veya bir hayvanın uzuvlarını kesmek; veya (ülkeyi/kurumu) parçalara bölmek","e1":"The empire was dismembered after the war.","e1t":"İmparatorluk savaştan sonra parçalandı (bölündü).","e2":"To dismember a corpse.","e2t":"Bir cesedi parçalamak."},{"w":"disparate","tr":"tamamen farklı / bambaşka / uyumsuz","te":"Adjective","tt":"Sıfat","de":"Essentially different in kind; not allowing comparison","dt":"Tür olarak esasen farklı olan; karşılaştırma kabul etmez","e1":"Disparate cultures.","e1t":"Birbirinden tamamen farklı (bambaşka) kültürler.","e2":"The disparate elements of the plan.","e2t":"Planın birbiriyle alakasız (farklı) öğeleri."},{"w":"disparity","tr":"eşitsizlik / uçurum / farklılık","te":"Noun","tt":"İsim","de":"A great difference","dt":"Büyük farklılık; dengesizlik","e1":"The disparity between the rich and the poor.","e1t":"Zengin ve fakir arasındaki uçurum (eşitsizlik).","e2":"Economic disparities.","e2t":"Ekonomik farklılıklar."},{"w":"dispatch / despatch","tr":"göndermek / sevk etmek / hızla halletmek / (resmi) rapor","te":"Verb/Noun","tt":"Fiil/İsim","de":"Send off to a destination or for a purpose; or to deal with a task quickly","dt":"Bir yere/amaca göndermek; veya bir işi hızla bitirmek","e1":"To dispatch a messenger.","e1t":"Bir ulak (haberci) göndermek.","e2":"He dispatched the business in an hour.","e2t":"İşi bir saat içinde (hızla) halletti."},{"w":"dispersal","tr":"dağılma / yayılma","te":"Noun","tt":"İsim","de":"The action or process of distributing things or people over a wide area","dt":"Şeylerin veya insanların geniş bir alana dağıtılması eylemi","e1":"The dispersal of seeds by the wind.","e1t":"Tohumların rüzgarla yayılması.","e2":"Police ordered the dispersal of the crowd.","e2t":"Polis kalabalığın dağılmasını emretti."},{"w":"disport","tr":"eğlenmek / oynaşmak","te":"Verb","tt":"Fiil","de":"Enjoy oneself unrestrainedly; frolic","dt":"Serbestçe eğlenmek; oynaşmak/keyif sürmek","e1":"Children disporting themselves on the beach.","e1t":"Sahilde eğlenen (oynaşan) çocuklar.","e2":"To disport oneself in the sun.","e2t":"Güneşte keyif çatmak."},{"w":"disproportionate","tr":"orantısız / dengesiz","te":"Adjective","tt":"Sıfat","de":"Too large or too small in comparison with something else","dt":"Başka bir şeye kıyasla çok büyük veya çok küçük; dengesiz","e1":"A disproportionate amount of time.","e1t":"Orantısız (aşırı) miktarda zaman.","e2":"Disproportionate use of force.","e2t":"Orantısız güç kullanımı."},{"w":"disputatious","tr":"kavgacı / tartışmayı seven","te":"Adjective","tt":"Sıfat","de":"Fond of or causing heated arguments","dt":"Tartışmaya veya kavgaya meyilli","e1":"A disputatious person.","e1t":"Tartışmacı (geçimsiz) biri.","e2":"Disputatious atmosphere.","e2t":"Tartışmalı (gergin) ortam."},{"w":"disquiet","tr":"huzursuzluk / endişe / tedirgin etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of anxiety or worry","dt":"Endişe veya huzursuzluk hissi","e1":"Public disquiet about the economy.","e1t":"Ekonomi hakkında halktaki huzursuzluk.","e2":"The news disquieted her.","e2t":"Haberler onu tedirgin etti (huzursuz etti)."},{"w":"disquisition","tr":"inceleme / bilimsel araştırma / tez","te":"Noun","tt":"İsim","de":"A long or elaborate essay or discussion on a particular subject","dt":"Belirli bir konu üzerinde uzun ve detaylı yazı veya tartışma","e1":"A learned disquisition on ancient history.","e1t":"Antik tarih üzerine akademik bir inceleme (tez).","e2":"Disquisitionary (adjective).","e2t":""},{"w":"dissection","tr":"diseksiyon / kadavra inceleme / detaylı analiz","te":"Noun","tt":"İsim","de":"The action of dissecting a body or plant to study its internal parts; or detailed analysis","dt":"İç kısımları incelemek için vücut veya bitkiyi parçalara ayırma; veya detaylı analiz","e1":"To perform a dissection in biology class.","e1t":"Biyoloji dersinde diseksiyon (kadavra inceleme) yapmak.","e2":"Dissection of a complex problem.","e2t":"Karmaşık bir sorunun detaylı analizi."},{"w":"dissemble","tr":"duygularını gizlemek / olduğundan farklı görünmek / riyakarlık yapmak","te":"Verb","tt":"Fiil","de":"Conceal one's true motives, feelings, or beliefs","dt":"Gerçek niyet, duygu veya inançlarını gizlemek","e1":"He dissembled his fear with a smile.","e1t":"Korkusunu bir gülümsemeyle gizledi.","e2":"A politician who knows how to dissemble.","e2t":"Nasıl rol yapacağını (gerçek niyetini gizleyeceğini) bilen bir siyasetçi."},{"w":"dissension","tr":"anlaşmazlık / nifak / görüş ayrılığı","te":"Noun","tt":"İsim","de":"Disagreement that leads to discord","dt":"Anlaşmazlığa (huzursuzluğa) yol açan görüş ayrılığı","e1":"To sow seeds of dissension.","e1t":"Nifak (anlaşmazlık) tohumları ekmek.","e2":"Dissension within the party.","e2t":"Parti içindeki görüş ayrılıkları."},{"w":"dissimulate","tr":"(gerçeği/duyguyu) gizlemek / numara yapmak","te":"Verb","tt":"Fiil","de":"Conceal or disguise one's thoughts, feelings, or character","dt":"Düşünce, duygu veya karakterini gizlemek (olduğundan farklı görünmek)","e1":"He found it hard to dissimulate his grief.","e1t":"Kederini gizlemekte (numara yapmakta) zorlandı.","e2":"Dissimulation (noun).","e2t":"Duygu/niyet gizleme."},{"w":"dissolute","tr":"ahlaksız / sefih / hayta","te":"Adjective","tt":"Sıfat","de":"Lax in morals; licentious","dt":"Ahlaki değerleri gevşek; sefahat içinde yaşayan","e1":"To lead a dissolute life.","e1t":"Ahlaksız (başıboş) bir hayat sürmek.","e2":"A dissolute young man.","e2t":"Sefih (hayta) bir genç."},{"w":"dissolution","tr":"fesih / dağılma / ayrışma / ölüm","te":"Noun","tt":"İsim","de":"The closing down or dismissal of an assembly, partnership, or official body; or the action of dissolving","dt":"Bir kurumun, ortaklığın veya meclisin kapatılması (feshi); veya çözünme","e1":"The dissolution of parliament.","e1t":"Parlamentonun feshedilmesi (dağıtılması).","e2":"The dissolution of a marriage.","e2t":"Evliliğin sona ermesi (boşanma)."},{"w":"distrait","tr":"dalgın / unutkan / kafası dağınık","te":"Adjective","tt":"Sıfat","de":"Distracted or absent","dt":"minded","e1":"Dikkati dağılmış veya dalgın","e1t":"He seemed distrait and answered vaguely.","e2":"Dalgın görünüyordu ve kaçamak cevaplar verdi.","e2t":"(Daha çok Fransızca kökenli edebi bir kullanım)."},{"w":"diurnal","tr":"günlük / gündüze ait","te":"Adjective","tt":"Sıfat","de":"Of or during the day; or daily","dt":"Gündüz olan veya gündüze ait; veya günlük","e1":"Diurnal animals (active during the day).","e1t":"Gündüz faal olan hayvanlar.","e2":"Diurnal rotation of the Earth.","e2t":"Dünya'nın günlük dönüşü. (Not: 'Nocturnal'"},{"w":"diva","tr":"diva / ünlü kadın sanatçı","te":"Noun","tt":"İsim","de":"A famous female opera singer; or a self","dt":"important woman","e1":"Ünlü kadın opera sanatçısı; veya kendini çok önemli gören (kaprisli) kadın","e1t":"An opera diva.","e2":"Opera divası.","e2t":"She's a bit of a diva."},{"w":"divergent","tr":"farklı / sapan / ayrılan","te":"Adjective","tt":"Sıfat","de":"Tending to be different or develop in different directions","dt":"Farklı olma veya farklı yönlerde gelişme eğiliminde olan","e1":"Divergent views.","e1t":"Farklı (ayrılan) görüşler.","e2":"Divergent evolution (biology).","e2t":"Iraksak (ayrılan) evrim."},{"w":"docket","tr":"dosya / ajanda / duruşma listesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A calendar or list of cases for trial or people having cases pending; or to label","dt":"Duruşma listesi veya ajanda; veya bir dosyayı etiketlemek/kaydetmek","e1":"The judge has a crowded docket this week.","e1t":"Yargıcın bu hafta yoğun bir duruşma listesi var.","e2":"To docket a case.","e2t":"Bir davayı kayda geçirmek (etiketlemek)."},{"w":"doctrinaire","tr":"doktriner / katı fikirli / kuramcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Seeking to impose a doctrine without regard to practical considerations","dt":"Pratik sonuçları önemsemeden bir öğretiyi (doktrini) dayatmaya çalışan","e1":"A doctrinaire approach to economics.","e1t":"Ekonomiye katı (teorik) bir yaklaşım.","e2":"He is too doctrinaire to listen to common sense.","e2t":"Sağduyuyu dinleyemeyecek kadar katı fikirli."},{"w":"dodder","tr":"titremek (yaşlılıktan) / sendelemek","te":"Verb","tt":"Fiil","de":"Tremble or totter, typically because of old age","dt":"Genellikle yaşlılık nedeniyle titremek veya sarsak adımlarla yürümek","e1":"A doddering old man.","e1t":"Eli ayağı titreyen ihtiyar.","e2":"He doddered across the room.","e2t":"Odanın içinde sendeleyerek yürüdü."},{"w":"doff","tr":"(şapka/giysi) çıkarmak / selamlamak","te":"Verb","tt":"Fiil","de":"Remove (an item of clothing); or to tip (one's hat) as a greeting","dt":"(Giysiyi) çıkarmak; veya (şapkayı) selam vermek için hafifçe kaldırmak/çıkarmak","e1":"To doff your hat to someone.","e1t":"Birine şapka çıkararak selam vermek.","e2":"He doffed his coat as he entered.","e2t":"İçeri girerken ceketini çıkardı. (Not: 'Don'"},{"w":"doggerel","tr":"tekerleme / basit ve kaba şiir","te":"Noun","tt":"İsim","de":"Comic verse composed in irregular rhythm","dt":"Düzensiz ritimle yazılmış komik veya basit şiir/tekerleme","e1":"To write doggerel for a birthday card.","e1t":"Doğum günü kartı için basit bir tekerleme yazmak.","e2":"This isn't poetry; it's just doggerel.","e2t":"Bu şiir değil; sadece uyduruk bir tekerleme."},{"w":"doldrums","tr":"durgunluk / moral bozukluğu / rüzgarsız bölge","te":"Noun","tt":"İsim (Plural)","de":"A state or period of inactivity, stagnation, or depression","dt":"Hareketsizlik, durgunluk veya depresyon dönemi","e1":"The economy is in the doldrums.","e1t":"Ekonomi durgunluk (çöküş) içinde.","e2":"To be in the doldrums (to feel low).","e2t":"Morali bozuk (keyifsiz) olmak."},{"w":"dole","tr":"işsizlik maaşı / sadaka / (parça parça) dağıtmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Benefit paid by the state to the unemployed; or to distribute shares of something","dt":"Devletin işsizlere ödediği maaş; veya (bir şeyi) azar azar dağıtmak","e1":"To be on the dole.","e1t":"İşsizlik maaşıyla geçinmek.","e2":"To dole out food to the poor.","e2t":"Fakirlere yiyecek dağıtmak."},{"w":"dolorous","tr":"acı veren / kederli / dertli","te":"Adjective","tt":"Sıfat","de":"Feeling or expressing great sorrow or distress","dt":"Büyük bir keder veya sıkıntı hisseden/ifade eden (edebi)","e1":"A dolorous tale of loss.","e1t":"Acı dolu bir kayıp hikayesi.","e2":"Dolorous cries.","e2t":"Kederli haykırışlar."},{"w":"dolt","tr":"ebleh / aptal / bön","te":"Noun","tt":"İsim","de":"A stupid person","dt":"Aptal (akılsız) kişi","e1":"Don't be such a dolt!","e1t":"Bu kadar ebleh olma!","e2":"Doltish (adjective).","e2t":"Aptalca."},{"w":"domicile","tr":"ikametgah / konut / yerleşmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The country that a person treats as their permanent home; or to settle","dt":"Bir kişinin kalıcı evi olarak kabul ettiği yer; ikametgah","e1":"His legal domicile is Turkey.","e1t":"Onun yasal ikametgahı Türkiye'dir.","e2":"To be domiciled in London.","e2t":"Londra'da ikamet etmek."},{"w":"domineer","tr":"tahakküm etmek / zorbalık taslamak","te":"Verb","tt":"Fiil","de":"Assert one's will over another in an arrogant way","dt":"Başkasına kibirli bir şekilde iradesini dayatmak","e1":"A domineering mother.","e1t":"Baskın (her şeye karışan) bir anne.","e2":"He likes to domineer over his subordinates.","e2t":"Astlarına zorbalık taslamayı (tahakküm etmeyi) sever."},{"w":"don","tr":"giymek / takmak / bey / öğretim üyesi (İngiltere)","te":"Verb/Noun","tt":"Fiil/İsim","de":"To put on (an item of clothing); or a university teacher; or a Spanish title","dt":"(Giysiyi) giymek; veya üniversite öğretim üyesi; veya İspanyolca unvan","e1":"To don a uniform.","e1t":"Üniforma giymek.","e2":"To don a mask.","e2t":"Maske takmak."},{"w":"dormitory","tr":"yatakhane / öğrenci yurdu","te":"Noun","tt":"İsim","de":"A large bedroom for a number of people in a school or institution; or a residence hall","dt":"Bir kurumdaki çok kişilik yatakhane; veya yurt binası","e1":"To sleep in a school dormitory.","e1t":"Okul yatakhanesinde uyumak.","e2":"Dormitory town (suburb).","e2t":"Yatakhane şehir (insanların sadece uyumaya geldiği banliyö)."},{"w":"dorsal","tr":"sırtla ilgili / sırtta bulunan","te":"Adjective","tt":"Sıfat","de":"Of, on, or relating to the upper side or back of an animal, plant, or organ","dt":"Bir hayvanın, bitkinin veya organın sırt kısmıyla ilgili","e1":"A shark's dorsal fin.","e1t":"Köpekbalığının sırt yüzgeci.","e2":"The dorsal surface of the hand.","e2t":"Elin sırt yüzeyi. (Not: 'Ventral'"},{"w":"dosage","tr":"dozaj / ölçek","te":"Noun","tt":"İsim","de":"The size or frequency of a dose of a medicine or drug","dt":"İlacın miktarı veya verilme sıklığı","e1":"A high dosage of antibiotics.","e1t":"Yüksek dozda antibiyotik.","e2":"To increase the dosage.","e2t":"Dozu artırmak."},{"w":"dossier","tr":"dosya / döküman seti (kişi/olay hakkında)","te":"Noun","tt":"İsim","de":"A collection of documents about a particular person, event, or subject","dt":"Belirli bir kişi veya olay hakkında toplanmış belgeler bütünü","e1":"To compile a dossier on a suspect.","e1t":"Bir şüpheli hakkında dosya hazırlamak.","e2":"A secret intelligence dossier.","e2t":"Gizli istihbarat dosyası."},{"w":"dotage","tr":"bunaklık / ihtiyarlık dönemi","te":"Noun","tt":"İsim","de":"The period of life in which a person is old and weak","dt":"Bir kişinin yaşlı ve zayıf olduğu (genellikle zihinsel gerileme dönemi)","e1":"In his dotage.","e1t":"Bunaklık döneminde (iyice yaşlandığında).","e2":"He is entering his dotage.","e2t":"Artık yaşlılık dönemine giriyor."},{"w":"dote","tr":"üstüne titremek / çok sevmek / bunamak","te":"Verb","tt":"Fiil","de":"Be extremely and uncritically fond of; or to be senile","dt":"Birini aşırı derecede (eleştirmeden) sevmek; veya bunamak","e1":"To dote on your grandchildren.","e1t":"Torunlarının üstüne titremek.","e2":"A doting father.","e2t":"Çocuklarına düşkün (onları çok seven) baba."},{"w":"douse / dowse","tr":"su dökmek / (ateşi) söndürmek / daldırmak","te":"Verb","tt":"Fiil","de":"Pour a liquid over; drench; or extinguish (a fire)","dt":"Üzerine su dökmek (ıslatmak); veya ateşi söndürmek","e1":"To douse a fire with water.","e1t":"Ateşi suyla söndürmek.","e2":"He doused his head in cold water.","e2t":"Başını soğuk suya daldırdı."},{"w":"dowdy","tr":"rüküş / zevksiz (giyim) / modası geçmiş","te":"Adjective","tt":"Sıfat","de":"(Of a woman or her clothes) unfashionable and unstylish in appearance","dt":"(Kadın veya giysi için) modası geçmiş, zevksiz ve bakımsız","e1":"A dowdy dress.","e1t":"Rüküş bir elbise.","e2":"She looked rather dowdy.","e2t":"Oldukça rüküş (bakımsız) görünüyordu."},{"w":"draconian","tr":"drakonvari / çok sert / acımasız (yasa/önlem)","te":"Adjective","tt":"Sıfat","de":"(Of laws or their application) excessively harsh and severe","dt":"(Yasa veya uygulama için) aşırı sert ve acımasız","e1":"Draconian measures to control the protest.","e1t":"Protestoyu kontrol etmek için alınan çok sert önlemler.","e2":"Draconian punishments.","e2t":"Acımasız cezalar."},{"w":"dramatize / dramatise","tr":"oyunlaştırmak / abartmak","te":"Verb","tt":"Fiil","de":"Adapt (a novel or incident) as a play; or to exaggerate","dt":"(Bir romanı veya olayı) piyes haline getirmek; veya abartarak anlatmak","e1":"To dramatize a historical event for TV.","e1t":"Tarihsel bir olayı TV için oyunlaştırmak.","e2":"Don't dramatize the situation.","e2t":"Durumu abartma (dram haline getirme)."},{"w":"draught","tr":"hava akımı / cereyan / fıçı (içecek) / yudum / taslak","te":"Noun/Adj","tt":"A current of cool air in a room; or beer served from a cask; or a draft","de":"Odadaki hava akımı (cereyan); veya fıçıdan servis edilen içecek","dt":"To sit in a draught.","e1":"Cereyanda kalmak.","e1t":"Draught beer.","e2":"Fıçı bira.","e2t":""},{"w":"dribble","tr":"damlamak / ağzından su akmak / (basket/futbol) top sürmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a liquid) fall slowly in small drops; or to allow saliva to run from the mouth","dt":"(Sıvı için) damla damla akmak; veya salyası akmak; veya top sürmek","e1":"Water was dribbling from the tap.","e1t":"Musluktan su damlıyordu.","e2":"The baby dribbled on his chin.","e2t":"Bebeğin çenesinden salyası aktı."},{"w":"drivel","tr":"saçmalamak / zırva / salya","te":"Noun/Verb","tt":"İsim/Fiil","de":"Silly nonsense; or to let saliva flow from the mouth","dt":"Aptalca saçmalık (zırva); veya ağzından salya akıtmak","e1":"What a load of drivel!","e1t":"Ne kadar büyük bir zırva!","e2":"Stop drivelling!","e2t":"Saçmalamayı bırak!"},{"w":"droop","tr":"sarkmak / boynunu bükmek / çökmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Bend or hang downwards limply; or to sag from exhaustion","dt":"Gevşekçe aşağı sarkmak; veya bitkinlikten çökmek/boyun bükmek","e1":"The flowers were drooping in the heat.","e1t":"Çiçekler sıcakta boyunlarını bükmüştü (solmuştu).","e2":"His eyelids drooped.","e2t":"Göz kapakları (yorgunluktan) kapandı/sarktı."},{"w":"dross","tr":"cüruf / maden pisliği / değersiz atık","te":"Noun","tt":"İsim","de":"Something regarded as worthless; rubbish","dt":"Değersiz olarak görülen şey; çöp/atık","e1":"To separate the gold from the dross.","e1t":"Altını cürufundan (pisliğinden) ayırmak.","e2":"There is a lot of dross on television.","e2t":"Televizyonda bir sürü ıvır zıvır (değersiz şey) var."},{"w":"drudge","tr":"ağır ve sıkıcı işler yapan kimse / amele","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person made to do hard menial or dull work","dt":"Zor, sıradan ve sıkıcı işleri yapan kişi","e1":"A domestic drudge.","e1t":"Ev işleri kölesi (hizmetçisi).","e2":"To drudge away at a task.","e2t":"Bir iş üzerinde eşek gibi (ağır ağır) çalışmak."},{"w":"dubious","tr":"şüpheli / kuşkulu / tekinsiz","te":"Adjective","tt":"Sıfat","de":"Hesitating or doubting; or not to be relied upon; suspect","dt":"Tereddüt eden; veya güvenilmez; şüpheli","e1":"I am dubious about his chances of success.","e1t":"Onun başarı şansı konusunda şüpheliyim.","e2":"A dubious character.","e2t":"Tekinsiz (şüpheli) bir karakter."},{"w":"dulcet","tr":"kulağa hoş gelen / tatlı / yumuşak (ses)","te":"Adjective","tt":"Sıfat","de":"(Especially of sound) sweet and soothing","dt":"(Özellikle ses için) tatlı, dinlendirici ve hoş","e1":"The dulcet tones of a cello.","e1t":"Bir çellonun kulağa hoş gelen tonları.","e2":"Dulcet music.","e2t":"Yumuşak ve tatlı müzik."},{"w":"dupe","tr":"kandırmak / enayi / kurban","te":"Verb/Noun","tt":"Fiil/İsim","de":"Deceive; trick; or a victim of deception","dt":"Kandırmak; veya aldatılmış kişi (enayi)","e1":"He was duped into buying a fake painting.","e1t":"Sahte bir tabloyu almaya kandırıldı.","e2":"A naive dupe of the con artist.","e2t":"Dolandırıcının saf kurbanı."},{"w":"dwarf","tr":"cüce / küçültmek / gölgede bırakmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person, animal, or plant that is much smaller than the usual size; or to cause to seem small or insignificant","dt":"Cüce; veya bir şeyi (yanında) küçük veya önemsiz göstermek","e1":"The new skyscraper dwarfs the surrounding buildings.","e1t":"Yeni gökdelen etrafındaki binaları gölgede bırakıyor (küçük gösteriyor).","e2":"A white dwarf (astronomy).","e2t":"Beyaz cüce (yıldız)."},{"w":"dynamo","tr":"dinamo / jeneratör / ele avuca sığmaz kişi","te":"Noun","tt":"İsim","de":"A machine for converting mechanical energy into electrical energy; or an extremely energetic person","dt":"Mekanik enerjiyi elektriğe çeviren makine; veya bitmek bilmeyen enerjisi olan kişi","e1":"He is a real dynamo in the office.","e1t":"Ofiste tam bir enerji küpüdür.","e2":"Bicycle dynamo.","e2t":"Bisiklet dinamosu."},{"w":"dyslexia","tr":"disleksi / okuma güçlüğü","te":"Noun","tt":"İsim","de":"A general term for disorders that involve difficulty in learning to read or interpret words, letters, and other symbols","dt":"Kelime ve sembolleri algılama ve okumada yaşanan zorluk (öğrenme güçlüğü)","e1":"Children with dyslexia need special support.","e1t":"Disleksisi olan çocukların özel desteğe ihtiyacı vardır.","e2":"Dyslexic (adjective).","e2t":"Dislektik."},{"w":"dyspeptic","tr":"hazımsızlık çeken / asabi / huysuz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Suffering from indigestion; or irritable and bad","dt":"tempered","e1":"Hazımsızlıktan muzdarip; veya sinirli ve huysuz","e1t":"A dyspeptic old man.","e2":"Huysuz bir ihtiyar.","e2t":"Dyspepsia (noun)."},{"w":"earthy","tr":"toprağımsı / kaba / müstehcen / doğal","te":"Adjective","tt":"Sıfat","de":"Resembling or containing earth; or direct and uninhibited; robust","dt":"Toprak gibi; veya (espri/tavır için) kaba, açık sözlü ve doğal","e1":"An earthy smell.","e1t":"Toprak kokusu.","e2":"Earthy humor.","e2t":"Kaba (açık saçık) mizah."},{"w":"ebullient","tr":"coşkulu / kaynayan / hayat dolu","te":"Adjective","tt":"Sıfat","de":"Cheerful and full of energy; or (literary) boiling","dt":"Neşeli ve enerji dolu (coşkulu); veya (edebi) kaynayan","e1":"He was in an ebullient mood after the win.","e1t":"Galibiyetten sonra çok coşkulu bir ruh halindeydi.","e2":"Ebullience (noun).","e2t":"Coşku / Taşkınlık."},{"w":"eccentric","tr":"eksantrik / alışılmadık / dış merkezli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a person or their behavior) unconventional and slightly strange; or not placed centrally","dt":"Alışılmışın dışında ve biraz garip (kişi); veya merkezden kaçık","e1":"An eccentric billionaire.","e1t":"Eksantrik (garip huyları olan) milyarder.","e2":"Eccentric orbit (astronomy).","e2t":"Dış merkezli yörünge."},{"w":"ecclesiastic / ecclesiastical","tr":"kiliseye ait / ruhani","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the Christian Church or its clergy","dt":"Kilise veya din adamları ile ilgili","e1":"Ecclesiastical history.","e1t":"Kilise tarihi.","e2":"Ecclesiastic architecture.","e2t":"Dini mimari."},{"w":"echelon","tr":"kademe / rütbe / basamak","te":"Noun","tt":"İsim","de":"A level or rank in an organization, a profession, or society","dt":"Bir organizasyon veya toplumdaki rütbe veya basamak","e1":"The upper echelons of management.","e1t":"Yönetimin üst kademeleri.","e2":"To reach a high echelon.","e2t":"Yüksek bir mertebeye ulaşmak."},{"w":"éclat / eclat","tr":"başarı / görkem / parıltı","te":"Noun","tt":"İsim","de":"Brilliant display or effect; social distinction or conspicuous success","dt":"Büyük başarı; görkemli etki veya itibar","e1":"He played the role with great éclat.","e1t":"Rolü büyük bir başarıyla (görkemle) oynadı.","e2":"To perform with éclat.","e2t":"Parlak bir başarı sergilemek."},{"w":"ecologist","tr":"ekolog / çevre bilimci","te":"Noun","tt":"İsim","de":"A person who studies the relationship between living organisms and their environment","dt":"Canlıların çevreleriyle ilişkisini inceleyen bilim insanı","e1":"The ecologist warned about the loss of biodiversity.","e1t":"Ekolog biyolojik çeşitlilik kaybı konusunda uyardı.","e2":"Ecology (noun).","e2t":"Ekoloji."},{"w":"economical","tr":"tutumlu / tasarruflu / az masraflı","te":"Adjective","tt":"Sıfat","de":"Giving good value or service in relation to the amount of money, time, or effort spent","dt":"Para, zaman veya çaba açısından tasarruflu; tutumlu","e1":"An economical car.","e1t":"Az yakan (ekonomik) bir araba.","e2":"He is very economical with his words (concise).","e2t":"Kelimelerini çok tutumlu kullanır (az ve öz konuşur)."},{"w":"ecstasy","tr":"vecd / kendinden geçme / mest olma","te":"Noun","tt":"İsim","de":"An overwhelming feeling of great happiness or joyful excitement","dt":"Çok büyük bir mutluluk veya coşkuyla kendinden geçme hali","e1":"To be in an ecstasy of delight.","e1t":"Sevinçten mest olmak (vecd içinde olmak).","e2":"Ecstatic (adjective).","e2t":"Çok mutlu / Mest olmuş."},{"w":"eddy","tr":"anafor / girdap / ters akıntı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A circular movement of water, counter to a main current, causing a small whirlpool","dt":"Ana akıntıya zıt yönde oluşan dairesel su hareketi (küçük girdap)","e1":"Eddies of dust in the street.","e1t":"Sokaktaki toz hortumları (girdapları).","e2":"The water eddied around the rocks.","e2t":"Su kayaların etrafında girdaplar oluşturdu."},{"w":"edification","tr":"aydınlanma / (manevi/zihinsel) gelişim","te":"Noun","tt":"İsim","de":"The instruction or improvement of a person morally or intellectually","dt":"Bir kişinin ahlaki veya zihinsel olarak gelişmesi/eğitilmesi","e1":"For your own edification.","e1t":"Kendi gelişiminiz (aydınlanmanız) için.","e2":"Edify (verb).","e2t":"Aydınlatmak / Geliştirmek."},{"w":"edifice","tr":"büyük yapı / bina / sistem","te":"Noun","tt":"İsim","de":"A building, especially a large, imposing one; or a complex system of beliefs","dt":"Özellikle büyük ve görkemli bina; veya karmaşık inanç/düşünce sistemi","e1":"A magnificent stone edifice.","e1t":"Muhteşem bir taş yapı.","e2":"The whole edifice of trust collapsed.","e2t":"Tüm güven sistemi (yapısı) çöktü."},{"w":"edify","tr":"aydınlatmak / bilgilendirmek / (manevi) eğitmek","te":"Verb","tt":"Fiil","de":"Instruct or improve (someone) morally or intellectually","dt":"Birini ahlaki veya zihinsel yönden eğitmek/geliştirmek","e1":"To edify the soul.","e1t":"Ruhu terbiye etmek (aydınlatmak).","e2":"A speech intended to edify the public.","e2t":"Halkı bilgilendirmeyi amaçlayan bir konuşma."},{"w":"effeminate","tr":"kadınsı / kılıbık / zayıf karakterli (erkek için)","te":"Adjective","tt":"Sıfat","de":"(Of a man) having characteristics regarded as typical of a woman; unmanly","dt":"(Erkek için) kadınsı özellikler taşıyan (genellikle aşağılayıcı)","e1":"An effeminate voice.","e1t":"Kadınsı bir ses.","e2":"His manners were somewhat effeminate.","e2t":"Tavırları biraz kadınsıydı."},{"w":"effervescence","tr":"köpürme / fıkırdama / coşku","te":"Noun","tt":"İsim","de":"Bubbles in a liquid; fizz; or vivacity and enthusiasm","dt":"Sıvıdaki kabarcıklar; veya canlılık ve coşku","e1":"The effervescence of sparkling wine.","e1t":"Köpüklü şarabın fıkırdaması.","e2":"Her natural effervescence.","e2t":"Onun doğal coşkusu (neşesi)."},{"w":"effete","tr":"tükenmiş / yozlaşmış / etkisiz","te":"Adjective","tt":"Sıfat","de":"(Of a person) affected, over","dt":"refined, and ineffectual; or no longer capable of effective action","e1":"(Kişi/kurum için) gücünü kaybetmiş, yozlaşmış ve etkisiz","e1t":"An effete aristocracy.","e2":"Gücünü yitirmiş (yozlaşmış) aristokrasi.","e2t":"To feel old and effete."},{"w":"efflorescence","tr":"çiçeklenme / parlayış / (hastalık) döküntü","te":"Noun","tt":"İsim","de":"The state or a period of flowering; or an example or result of growth and development","dt":"Çiçeklenme dönemi; veya gelişim/başarının doruk noktası","e1":"The efflorescence of Victorian culture.","e1t":"Victoria dönemi kültürünün parlayışı (altın çağı).","e2":"Skin efflorescence (rash).","e2t":"Deri döküntüsü."},{"w":"effluence","tr":"dışarı akma / atık","te":"Noun","tt":"İsim","de":"A substance that flows out from something","dt":"Bir şeyden dışarı akan madde (atık su vb.)","e1":"Industrial effluence in the river.","e1t":"Nehirdeki endüstriyel atık akışı.","e2":"Effluent (noun).","e2t":"Atık su."},{"w":"effluvia / effluvium","tr":"nahoş koku / buhar / atık (gaz)","te":"Noun","tt":"İsim","de":"An unpleasant or harmful odor, secretion, or discharge","dt":"Nahoş veya zararlı koku, salgı veya duman","e1":"The effluvia from the garbage dump.","e1t":"Çöp döküm alanından gelen kötü kokular.","e2":"Malodorous effluvium.","e2t":"Kötü kokulu buhar/gaz."},{"w":"effusion","tr":"sızıntı / dışarı dökülme / (duygu) taşkınlığı","te":"Noun","tt":"İsim","de":"An instance of giving off something such as a liquid, light, or smell; or an unrestrained expression of feelings","dt":"Sıvı, ışık veya koku sızıntısı; veya duyguların ölçüsüzce dışa vurumu","e1":"A pleural effusion (medicine).","e1t":"Akciğer zarı su toplaması (sıvı birikmesi).","e2":"Emotional effusions.","e2t":"Duygu taşkınlıkları (aşırı duygusal konuşma)."},{"w":"egotism","tr":"bencillik / benmerkezcilik / egoizm","te":"Noun","tt":"İsim","de":"The practice of talking and thinking about oneself excessively because of an undue sense of self","dt":"importance","e1":"Aşırı öz","e1t":"önem duygusu nedeniyle sürekli kendinden bahsetme ve kendini düşünme","e2":"His egotism made him unpopular.","e2t":"Bencilliği onu sevilmeyen biri yaptı."},{"w":"egregious","tr":"çok kötü / göze batan / fahiş (hata vb.)","te":"Adjective","tt":"Sıfat","de":"Outstandingly bad; shocking","dt":"Şok edici derecede kötü; bariz (olumsuz anlamda)","e1":"An egregious error.","e1t":"Vahim (fahiş) bir hata.","e2":"Egregious behavior.","e2t":"Kabul edilemez (berbat) davranış."},{"w":"egress","tr":"çıkış / dışarı çıkma","te":"Noun/Verb","tt":"İsim/Fiil","de":"The action of going out of or leaving a place; an exit","dt":"Bir yerden dışarı çıkma eylemi; çıkış yeri","e1":"To provide a means of egress in case of fire.","e1t":"Yangın durumunda bir çıkış imkanı sağlamak.","e2":"Points of ingress and egress.","e2t":"Giriş ve çıkış noktaları."},{"w":"ejaculation","tr":"birden söyleyiverme / haykırma / boşalma","te":"Noun","tt":"İsim","de":"A sudden spoken remark, especially one expressing a strong emotion; or the action of ejecting semen","dt":"Güçlü bir duyguyu ifade eden ani söz; veya (biyolojik) boşalma","e1":"A short ejaculation of surprise.","e1t":"Şaşkınlıkla ağızdan kaçan kısa bir nida.","e2":"Premature ejaculation.","e2t":"Erken boşalma."},{"w":"elaboration","tr":"detaylandırma / özenle hazırlama / derinleştirme","te":"Noun","tt":"İsim","de":"The addition of more detail concerning what has already been said; or the process of developing something in detail","dt":"Zaten söylenmiş bir şeye daha fazla detay ekleme; veya bir şeyi detaylıca geliştirme süreci","e1":"This point needs further elaboration.","e1t":"Bu noktanın daha fazla detaylandırılmaya ihtiyacı var.","e2":"The elaboration of a new theory.","e2t":"Yeni bir teorinin özenle geliştirilmesi."},{"w":"elegy","tr":"ağıt / hüzünlü şiir","te":"Noun","tt":"İsim","de":"A poem of serious reflection, typically a lament for the dead","dt":"Genellikle bir ölünün ardından yazılan ciddi ve hüzünlü şiir","e1":"Gray's \"Elegy Written in a Country Churchyard\".","e1t":"Gray'in meşhur ağıtı.","e2":"Elegiac (adjective).","e2t":"Hüzünlü / Ağıt gibi."},{"w":"elevate","tr":"yükseltmek / yüceltmek / (moral) düzeltmek","te":"Verb","tt":"Fiil","de":"Raise or lift to a higher position; or to promote to a higher rank","dt":"Daha yüksek bir konuma kaldırmak; veya rütbesini artırmak","e1":"To elevate the feet.","e1t":"Ayakları yükseğe kaldırmak.","e2":"He was elevated to the peerage.","e2t":"Soyluluk mertebesine yükseltildi."},{"w":"elixir","tr":"iksir / her derde deva","te":"Noun","tt":"İsim","de":"A magical or medicinal potion; or a particular liquid that is believed to cure all ills","dt":"Sihirli veya tıbbi içecek; veya her derde deva olduğuna inanılan sıvı","e1":"The elixir of life.","e1t":"Ölümsüzlük (hayat) iksiri.","e2":"An elixir for all social problems.","e2t":"Tüm sosyal sorunlar için bir iksir (çare)."},{"w":"ellipsis","tr":"elips / eksiltme / üç nokta (...)","te":"Noun","tt":"İsim","de":"The omission from speech or writing of a word or words that are superfluous; or a set of three dots","dt":"Yazıda veya konuşmada gereksiz kelimelerin çıkarılması; veya üç nokta işareti","e1":"To use an ellipsis to indicate a pause.","e1t":"Duraklamayı belirtmek için üç nokta kullanmak.","e2":"Elliptical (adjective).","e2t":"Kelime eksiltmeli / Elips şeklinde."},{"w":"elliptical / elliptic","tr":"eliptik / kapalı (söz) / eksiltmeli","te":"Adjective","tt":"Sıfat","de":"(Of speech or writing) tending to be ambiguous or cryptic; or oval in shape","dt":"(Söz/yazı için) belirsiz veya kapalı; veya oval (elips şeklinde)","e1":"An elliptical remark.","e1t":"Kapalı (anlaşılması güç) bir yorum.","e2":"The Earth's elliptical orbit.","e2t":"Dünya'nın eliptik (oval) yörüngesi."},{"w":"eloquence","tr":"hitabet yeteneği / güzel ve etkili konuşma","te":"Noun","tt":"İsim","de":"Fluent or persuasive speaking or writing","dt":"Akıcı ve ikna edici konuşma veya yazma becerisi","e1":"A speaker of great eloquence.","e1t":"Büyük bir hitabet yeteneği olan konuşmacı.","e2":"Eloquent (adjective).","e2t":"Hitabeti güçlü / Etkili."},{"w":"elucidate","tr":"açıklığa kavuşturmak / izah etmek","te":"Verb","tt":"Fiil","de":"Make (something) lucid or clear; explain","dt":"Bir şeyi anlaşılır kılmak; açıklamak","e1":"To elucidate a complex theory.","e1t":"Karmaşık bir teoriyi izah etmek.","e2":"Please elucidate your reasons for leaving.","e2t":"Lütfen ayrılma nedenlerinizi açıklığa kavuşturun."},{"w":"elysian","tr":"elizyen / cennet gibi / huzurlu","te":"Adjective","tt":"Sıfat","de":"Relating to or characteristic of heaven or paradise","dt":"Cennetle ilgili veya cennet gibi (huzur dolu)","e1":"Elysian Fields (mythology).","e1t":"Elizyen tarlaları (cennet bahçeleri).","e2":"An elysian peace.","e2t":"Cennetvari bir huzur."},{"w":"emasculate","tr":"erkekliğini almak / gücünü kırmak / etkisizleştirmek","te":"Verb","tt":"Fiil","de":"Deprive (a man) of his male identity; or make someone or something weaker or less effective","dt":"(Erkeği) erkeklik gururundan yoksun bırakmak; veya birini/bir şeyi zayıflatmak/etkisizleştirmek","e1":"The law was emasculated by amendments.","e1t":"Yasa, yapılan değişikliklerle etkisizleştirildi (kuşa döndürüldü).","e2":"He felt emasculated by her criticism.","e2t":"Onun eleştirileriyle gururu kırılmış (kendini güçsüz) hissetti."},{"w":"embargo","tr":"ambargo / yasak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An official ban on trade or other commercial activity with a particular country","dt":"Belirli bir ülkeyle yapılan ticarete veya ticari faaliyete getirilen resmi yasak","e1":"To impose an arms embargo.","e1t":"Silah ambargosu uygulamak.","e2":"The news is under embargo until tomorrow.","e2t":"Haber yarına kadar yayın yasağı (ambargosu) altında."},{"w":"embed","tr":"gömmek / yerleştirmek / oturtmak","te":"Verb","tt":"Fiil","de":"Fix (an object) firmly and deeply in a surrounding mass","dt":"(Bir nesneyi) çevreleyen bir kütlenin içine sıkıca ve derince yerleştirmek","e1":"The bullet was embedded in the wall.","e1t":"Kurşun duvara saplanmıştı (gömülmüştü).","e2":"Embedded journalists.","e2t":"(Askeri birlik içine) yerleştirilmiş gazeteciler."},{"w":"embroider","tr":"nakış işlemek / süslemek / (hikaye) uydurmak","te":"Verb","tt":"Fiil","de":"Decorate (cloth) by sewing patterns on it with thread; or to add fictitious ornaments to a narrative","dt":"(Kumaş üzerine) nakış işlemek; veya bir anlatıya hayali süslemeler eklemek","e1":"To embroider a cushion cover.","e1t":"Bir yastık kılıfına nakış işlemek.","e2":"He tends to embroider the facts.","e2t":"Gerçekleri (abartarak/süsleyerek) anlatmaya meyillidir."},{"w":"embryo","tr":"embriyo / cenin / başlangıç aşaması","te":"Noun","tt":"İsim","de":"An unborn or unhatched offspring in the process of development","dt":"Gelişim aşamasındaki doğmamış canlı; embriyo","e1":"The project is still in embryo (in its early stages).","e1t":"Proje henüz başlangıç aşamasında (embriyo halinde).","e2":"Embryonic (adjective).","e2t":"Embriyonik / Başlangıç halindeki."},{"w":"emend","tr":"(metni) düzeltmek / hatasını gidermek","te":"Verb","tt":"Fiil","de":"Make corrections and improvements to (a text)","dt":"(Metin üzerinde) düzeltme ve iyileştirme yapmak","e1":"To emend a manuscript.","e1t":"Bir el yazmasını düzeltmek.","e2":"Emendation (noun).","e2t":"Metin düzeltme. (Not: 'Amend' daha çok yasa/davranış için kullanılır)."},{"w":"emeritus","tr":"emekli (unvanını koruyan) / emektar","te":"Adjective","tt":"Sıfat","de":"(Of the former holder of an office, especially a university professor) having retired but allowed to retain their title as an honor","dt":"(Özellikle profesörler için) emekli olduğu halde unvanını şeref payesi olarak taşıyan","e1":"Professor emeritus.","e1t":"Emekli (onursal) profesör.","e2":"","e2t":""},{"w":"emetic","tr":"kusturucu (ilaç)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"(Of a substance) causing vomiting","dt":"Kusmaya neden olan (madde)","e1":"Salt water can act as an emetic.","e1t":"Tuzlu su kusturucu görev görebilir.","e2":"To administer an emetic.","e2t":"Kusturucu ilaç vermek."},{"w":"eminent","tr":"seçkin / yüce / üstün / ünlü","te":"Adjective","tt":"Sıfat","de":"(Of a person) famous and respected within a particular sphere; or used to emphasize a positive quality","dt":"Kendi alanında ünlü ve saygın; veya (olumlu özellik için) üstün","e1":"An eminent scientist.","e1t":"Seçkin bir bilim insanı.","e2":"A man of eminent good sense.","e2t":"Üstün sağduyulu bir adam."},{"w":"emollient","tr":"yumuşatıcı / yatıştırıcı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Having the quality of softening or soothing the skin; or attempting to avoid confrontation","dt":"Cildi yumuşatıcı; veya (tavır için) gerginliği azaltmaya çalışan/yatıştırıcı","e1":"An emollient cream.","e1t":"Yumuşatıcı krem.","e2":"He used an emollient tone to calm the crowd.","e2t":"Kalabalığı sakinleştirmek için yatıştırıcı bir ton kullandı."},{"w":"emolument","tr":"maaş / ücret / kazanç (mevkiden gelen)","te":"Noun","tt":"İsim","de":"A salary, fee, or profit from employment or office","dt":"Bir iş veya makamdan elde edilen maaş veya kazanç","e1":"The annual emoluments of the president.","e1t":"Başkanın yıllık maaş ve getirileri.","e2":"","e2t":""},{"w":"empathy","tr":"empati / duygudaşlık","te":"Noun","tt":"İsim","de":"The ability to understand and share the feelings of another","dt":"Başkasının duygularını anlama ve paylaşma yeteneği","e1":"To feel empathy for the victims.","e1t":"Mağdurlar için empati duymak.","e2":"Empathetic (adjective).","e2t":"Empatik."},{"w":"enamor / enamour","tr":"aşık etmek / büyülemek","te":"Verb","tt":"Fiil","de":"Be filled with a feeling of love for; have a liking or admiration for","dt":"Sevgiyle dolmak; hayranlık duymak","e1":"He was enamored of the local culture.","e1t":"Yerel kültüre hayran kalmıştı (vurulmuştu).","e2":"To be enamored with someone.","e2t":"Birine aşık olmak."},{"w":"encapsulate","tr":"özetlemek / kapsüllemek / içine almak","te":"Verb","tt":"Fiil","de":"Express the essential features of (something) succinctly; or to enclose in a capsule","dt":"(Bir şeyin) temel özelliklerini kısa ve öz şekilde ifade etmek; veya kapsül içine koymak","e1":"This short sentence encapsulates my whole philosophy.","e1t":"Bu kısa cümle tüm felsefemi özetliyor (içinde barındırıyor).","e2":"Encapsulated medicine.","e2t":"Kapsüllenmiş ilaç."},{"w":"encephalitis","tr":"ensefalit / beyin iltihabı","te":"Noun","tt":"İsim","de":"Inflammation of the brain, caused by infection or an allergic reaction","dt":"Enfeksiyon veya alerji kaynaklı beyin iltihabı","e1":"Viral encephalitis.","e1t":"Viral ensefalit.","e2":"Symptoms of encephalitis include headache and fever.","e2t":"Ensefalit belirtileri arasında baş ağrısı ve ateş bulunur."},{"w":"enchant","tr":"büyülemek / hayran bırakmak / efsunlamak","te":"Verb","tt":"Fiil","de":"Fill (someone) with great delight; charm; or to put under a spell","dt":"Birini büyülemek (hayran bırakmak); veya sihirli bir büyü altına almak","e1":"I was enchanted by the beautiful garden.","e1t":"Güzel bahçe karşısında büyülendim.","e2":"Enchanting (adjective).","e2t":"Büyüleyici."},{"w":"enclave","tr":"anklav / kuşatılmış toprak / kapalı topluluk","te":"Noun","tt":"İsim","de":"A portion of territory within or surrounded by a larger territory whose inhabitants are culturally or ethnically distinct","dt":"Başka bir devletin toprakları tarafından kuşatılmış toprak parçası; veya kapalı (ayrılmış) topluluk","e1":"A Turkish enclave in a foreign country.","e1t":"Yabancı bir ülkedeki Türk yerleşim bölgesi (anklav).","e2":"An enclave of wealthy houses.","e2t":"Zengin evlerin bulunduğu kapalı (ayrılmış) bölge."},{"w":"encroachment","tr":"tecavüz / izinsiz girme / sınır ihlali","te":"Noun","tt":"İsim","de":"Intrusion on a person's territory, rights, etc.","dt":"Birinin arazisine, haklarına veya alanına müdahale/tecavüz","e1":"The encroachment of the sea on the land.","e1t":"Denizin karayı (aşındırarak) işgal etmesi.","e2":"To protect against the encroachment of government power.","e2t":"Devlet gücünün (bireysel haklara) müdahalesine karşı korumak."},{"w":"encumber","tr":"engel olmak / yük olmak / ayak bağı olmak","te":"Verb","tt":"Fiil","de":"Restrict or burden (someone or something) in such a way that free action or movement is difficult","dt":"Hareket veya eylemi zorlaştıracak şekilde yük olmak veya kısıtlamak","e1":"He was encumbered by heavy luggage.","e1t":"Ağır bagajlar ona ayak bağı oluyordu.","e2":"A property encumbered with debts.","e2t":"Borç yükü altındaki (ipotekli) bir mülk."},{"w":"endear","tr":"sevdirmek / cana yakın kılmak","te":"Verb","tt":"Fiil","de":"Cause to be loved or liked","dt":"Sevilmesini veya beğenilmesini sağlamak","e1":"Her kindness endeared her to everyone.","e1t":"Nezaketi onu herkese sevdirdi.","e2":"An endearing habit.","e2t":"Cana yakın (sevimli) bir alışkanlık."},{"w":"endeavor / endeavour","tr":"çabalamak / gayret etmek / çaba","te":"Verb/Noun","tt":"Fiil/İsim","de":"Try hard to do or achieve something; or an enterprise or attempt","dt":"Bir şeyi başarmak için çok çalışmak; veya ciddi bir girişim/çaba","e1":"To endeavor to solve the problem.","e1t":"Sorunu çözmeye çabalamak.","e2":"Scientific endeavor.","e2t":"Bilimsel çaba (girişim)."},{"w":"endemic","tr":"endemik / bir yere özgü / yerel","te":"Adjective","tt":"Sıfat","de":"(Of a disease or condition) regularly found among particular people or in a certain area","dt":"(Hastalık veya bitki/hayvan için) sadece belirli bir bölgeye veya topluluğa özgü olan","e1":"Kangaroo is endemic to Australia.","e1t":"Kanguru Avustralya'ya özgüdür.","e2":"Corruption is endemic in the system.","e2t":"Yolsuzluk sistemin içine işlemiş (yerel bir sorun) durumda."},{"w":"endorse","tr":"onaylamak / desteklemek / (çek) arkasını imzalamak / (reklamda) tanıtmak","te":"Verb","tt":"Fiil","de":"Declare one's public approval or support of; or to sign a check","dt":"Bir şeyi resmen onaylamak veya desteklemek; veya çekin arkasını imzalamak (ciro etmek)","e1":"The committee endorsed the proposal.","e1t":"Komite öneriyi onayladı.","e2":"To endorse a product.","e2t":"Bir ürünün reklamını yapmak (tavsiye etmek)."},{"w":"endurance","tr":"dayanıklılık / sabır / tahammül","te":"Noun","tt":"İsim","de":"The fact or power of enduring an unpleasant or difficult process or situation without giving way","dt":"Zorlu bir duruma pes etmeden dayanma gücü","e1":"A test of physical endurance.","e1t":"Fiziksel dayanıklılık testi.","e2":"To be beyond endurance.","e2t":"Tahammül sınırlarının ötesinde olmak."},{"w":"energize / energise","tr":"enerji vermek / canlandırmak / harekete geçirmek","te":"Verb","tt":"Fiil","de":"Give vitality and enthusiasm to","dt":"Canlılık ve heves vermek","e1":"The news energized the campaign.","e1t":"Haberler kampanyayı canlandırdı (hareketlendirdi).","e2":"To energize a battery.","e2t":"Bir bataryayı şarj etmek (enerji yüklemek)."},{"w":"engross","tr":"(dikkatini) tamamen çekmek / kendini kaptırmak","te":"Verb","tt":"Fiil","de":"Absorb all the attention or interest of","dt":"Tüm dikkati veya ilgiyi üzerine çekmek","e1":"He was engrossed in his book.","e1t":"Kendini kitabına kaptırmıştı (tüm dikkati kitaptaydı).","e2":"An engrossing story.","e2t":"Sürükleyici (ilgi çekici) bir hikaye."},{"w":"enmity","tr":"düşmanlık / kin / nefret","te":"Noun","tt":"İsim","de":"The state or feeling of being actively opposed or hostile to someone or something","dt":"Birine veya bir şeye karşı aktif olarak karşıt veya düşmanca olma hissi","e1":"Years of enmity between the two families.","e1t":"İki aile arasındaki yıllarca süren düşmanlık.","e2":"Personal enmity.","e2t":"Kişisel husumet (kin)."},{"w":"ennui","tr":"can sıkıntısı / hayat bıkkınlığı","te":"Noun","tt":"İsim","de":"A feeling of listlessness and dissatisfaction arising from a lack of occupation or excitement","dt":"Meşguliyet veya heyecan eksikliğinden kaynaklanan halsizlik ve tatminsizlik hissi","e1":"To suffer from ennui.","e1t":"Hayat bıkkınlığından (can sıkıntısından) muzdarip olmak.","e2":"The ennui of a rainy afternoon.","e2t":"Yağmurlu bir öğleden sonrasının can sıkıntısı."},{"w":"enrapture","tr":"büyülemek / mest etmek / kendinden geçirmek","te":"Verb","tt":"Fiil","de":"Give intense pleasure or joy to","dt":"Büyük bir zevk veya neşe vermek","e1":"They were enraptured by the music.","e1t":"Müzikle mest oldular (kendilerinden geçtiler).","e2":"An enraptured audience.","e2t":"Büyülenmiş bir dinleyici kitlesi."},{"w":"enshrine","tr":"kutsal saymak / (yasa vb.) koruma altına almak / saklamak","te":"Verb","tt":"Fiil","de":"Place (a revered or precious object) in an appropriate receptacle; or preserve (a right/tradition)","dt":"(Değerli bir şeyi) bir yere yerleştirmek; veya (hak/gelenek gibi şeyleri) yasayla koruma altına almak","e1":"Civil rights are enshrined in the constitution.","e1t":"Sivil haklar anayasada (koruma altına alınmış) yer almaktadır.","e2":"The memory is enshrined in our hearts.","e2t":"Anısı kalbimizde yaşıyor (saklı)."},{"w":"ensnare","tr":"tuzağa düşürmek / kapana kıstırmak","te":"Verb","tt":"Fiil","de":"Catch in or as in a trap","dt":"Tuzağa düşürmek","e1":"He was ensnared by his own lies.","e1t":"Kendi yalanlarının tuzağına düştü.","e2":"To ensnare an animal.","e2t":"Bir hayvanı tuzağa düşürmek."},{"w":"entangle","tr":"karıştırmak / bulaştırmak / dolanmak","te":"Verb","tt":"Fiil","de":"Cause to become twisted together with or caught in; or involve in a difficult situation","dt":"Birbirine dolamak veya dolanmak; veya zor bir duruma bulaştırmak","e1":"To become entangled in a net.","e1t":"Bir ağa dolanmak.","e2":"He got entangled in a legal battle.","e2t":"Hukuki bir savaşa bulaştı."},{"w":"enthrall / enthral","tr":"büyülemek / esir etmek / hayran bırakmak","te":"Verb","tt":"Fiil","de":"Capture the fascinated attention of; enchant","dt":"İlgi ve hayranlığı üzerine çekmek; büyülemek","e1":"The children were enthralled by the circus.","e1t":"Çocuklar sirk karşısında büyülenmişti.","e2":"Enthralled by a story.","e2t":"Bir hikayeye dalıp gitmiş."},{"w":"entomology","tr":"entomoloji / böcek bilimi","te":"Noun","tt":"İsim","de":"The branch of zoology concerned with the study of insects","dt":"Böcekleri inceleyen zooloji dalı","e1":"A degree in entomology.","e1t":"Böcek bilimi diploması.","e2":"Entomologist (noun).","e2t":"Böcek bilimci."},{"w":"entourage","tr":"maiyet / eşlik edenler / çevre","te":"Noun","tt":"İsim","de":"A group of people attending or surrounding an important person","dt":"Önemli bir kişiye eşlik eden veya onun etrafında bulunan grup","e1":"The president arrived with a large entourage.","e1t":"Başkan kalabalık bir maiyetle geldi.","e2":"The star's entourage.","e2t":"Yıldızın etrafındaki ekip (çevre)."},{"w":"entrap","tr":"tuzağa düşürmek / kapana kıstırmak","te":"Verb","tt":"Fiil","de":"Catch in or as in a trap; or to trick someone into committing a crime","dt":"Birini tuzağa düşürmek veya (suç işlemesi için) kışkırtıp yakalatmak","e1":"He felt entrapped by the situation.","e1t":"Durum tarafından kapana kıstırılmış hissetti.","e2":"Entrapment (noun).","e2t":"Tuzağa düşürme / (Polisin) suç işletme tuzağı."},{"w":"entree / entrée","tr":"ana yemek / giriş hakkı / giriş yemeği","te":"Noun","tt":"İsim","de":"The main course of a meal; or the right to enter or join a particular sphere or group","dt":"Yemeğin ana kursu; veya belirli bir kitleye/gruba giriş hakkı","e1":"For my entree, I chose steak.","e1t":"Ana yemek olarak bifteği seçtim.","e2":"He has entree into the highest social circles.","e2t":"En üst sosyal çevrelere giriş hakkı (nüfuzu) var."},{"w":"enviable","tr":"kıskanılacak / imrenilecek","te":"Adjective","tt":"Sıfat","de":"Likely to excite envy","dt":"Kıskançlık uyandırması muhtemel; imrenilecek","e1":"An enviable position.","e1t":"Kıskanılacak bir konum.","e2":"He is in the enviable situation of having no debts.","e2t":"Hiç borcu olmama gibi imrenilecek bir durumda."},{"w":"environ","tr":"çevrelemek / kuşatmak","te":"Verb","tt":"Fiil","de":"Enclose or surround","dt":"Çevrelemek veya kuşatmak","e1":"A city environed by mountains.","e1t":"Dağlarla çevrili bir şehir.","e2":"Environs (noun","e2t":"plural: çevre / dolayları)."},{"w":"envisage","tr":"öngörmek / zihninde canlandırmak / tasavvur etmek","te":"Verb","tt":"Fiil","de":"Contemplate or conceive of as a possibility or a desirable future event","dt":"Bir olasılık veya gelecek olayı olarak düşünmek; hayal etmek","e1":"I don't envisage any problems.","e1t":"Herhangi bir sorun öngörmüyorum.","e2":"It is difficult to envisage how it will work.","e2t":"Nasıl çalışacağını tasavvur etmek (canlandırmak) zor."},{"w":"eon / aeon","tr":"devir / çağ / sonsuzluk","te":"Noun","tt":"İsim","de":"An indefinite and very long period of time; or a major division of geological time","dt":"Belirsiz ve çok uzun zaman dilimi; veya jeolojik zamanın ana bölümlerinden biri","e1":"It happened eons ago.","e1t":"Çağlar (devirler) önce oldu.","e2":"For eons to come.","e2t":"Gelecek sonsuz çağlar boyunca."},{"w":"epaulet / epaulette","tr":"apolet / omuzluk","te":"Noun","tt":"İsim","de":"An ornamental shoulder piece on an item of clothing, typically on a military uniform","dt":"Genellikle askeri üniformalarda bulunan süslü omuz parçası","e1":"Gold","e1t":"fringed epaulets.","e2":"Altın püsküllü apoletler.","e2t":"The captain's uniform had stars on the epaulettes."},{"w":"epicenter / epicentre","tr":"merkez üssü","te":"Noun","tt":"İsim","de":"The point on the earth's surface vertically above the focus of an earthquake","dt":"Deprem odağının tam üzerindeki yeryüzü noktası","e1":"The earthquake's epicenter was near Istanbul.","e1t":"Depremin merkez üssü İstanbul yakınlarındaydı.","e2":"The epicenter of the crisis.","e2t":"Krizin merkezi."},{"w":"epicure","tr":"gurme / ağız tadı sahibi / zevk düşkünü","te":"Noun","tt":"İsim","de":"A person who takes particular pleasure in fine food and drink","dt":"Kaliteli yemek ve içecekten özel zevk alan kişi","e1":"An epicure's delight.","e1t":"Bir gurmenin hazinesi (lezzeti).","e2":"Epicurean (adjective: zevk düşkünü / hazcı).","e2t":""},{"w":"epilogue / epilog","tr":"epilog / sonsöz","te":"Noun","tt":"İsim","de":"A section or speech at the end of a book or play that serves as a comment on or a conclusion to what has happened","dt":"Kitap veya oyunun sonunda yer alan yorum veya sonuç bölümü","e1":"The epilogue explains what happened to the characters years later.","e1t":"Sonsöz, karakterlere yıllar sonra ne olduğunu açıklar. (Not: 'Prologue'","e2":"önsöz","e2t":"zıttıdır)."},{"w":"epistemology","tr":"epistemoloji / bilgi felsefesi","te":"Noun","tt":"İsim","de":"The theory of knowledge, especially with regard to its methods, validity, and scope","dt":"Bilginin kaynağını, doğasını ve sınırlarını inceleyen felsefe dalı","e1":"Questions of epistemology.","e1t":"Bilgi felsefesi soruları.","e2":"Epistemological (adjective).","e2t":"Bilgi bilimsel."},{"w":"epithet","tr":"lakap / sıfat (tanımlayıcı)","te":"Noun","tt":"İsim","de":"An adjective or descriptive phrase expressing a quality characteristic of the person or thing mentioned","dt":"Bir kişinin veya nesnenin karakteristiğini ifade eden tanımlayıcı söz/sıfat","e1":"\"The Great\" is a famous epithet for Alexander.","e1t":"\"Büyük\", İskender için kullanılan meşhur bir lakaptır (sıfattır).","e2":"Racial epithets (insults).","e2t":"Irkçı hakaretler."},{"w":"epitomize / epitomise","tr":"özetlemek / timsali olmak / örneklemek","te":"Verb","tt":"Fiil","de":"Be a perfect example of; or to give a summary of","dt":"Mükemmel bir örneği olmak; veya özetlemek","e1":"This building epitomizes modern architecture.","e1t":"Bu bina modern mimariyi örnekler (onun timsalidir).","e2":"To epitomize a report.","e2t":"Bir raporu özetlemek."},{"w":"epoch","tr":"çağ / devir / dönem","te":"Noun","tt":"İsim","de":"A particular period of time in history or a person's life, typically one marked by notable events","dt":"Tarihte veya birinin hayatında önemli olaylarla işaretlenmiş dönem","e1":"A new epoch in the history of science.","e1t":"Bilim tarihinde yeni bir çağ (dönem).","e2":"Epoch","e2t":"making (adjective: çığır açan)."},{"w":"equable","tr":"dengeli / istikrarlı / yumuşak (iklim)","te":"Adjective","tt":"Sıfat","de":"Not easily disturbed or angered; or (of climate) not varying or fluctuating greatly","dt":"Kolayca bozulmayan veya sinirlenmeyen (sakin); veya (iklim için) aşırı dalgalanmayan","e1":"An equable temperament.","e1t":"Dengeli (sakin) bir mizaç.","e2":"An equable climate.","e2t":"Yumuşak ve istikrarlı bir iklim."},{"w":"equestrian","tr":"binici / atlı / binicilikle ilgili","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to horse riding; or a person who is a skilled horseback rider","dt":"Binicilikle ilgili; veya yetenekli binici","e1":"Equestrian sports.","e1t":"Binicilik sporları.","e2":"An equestrian statue (showing a person on a horse).","e2t":"Atlı heykel."},{"w":"equine","tr":"atla ilgili / atgillerden","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to or affecting horses or other members of the horse family","dt":"Atlarla veya at ailesiyle ilgili","e1":"Equine virus.","e1t":"At virüsü.","e2":"Equine features.","e2t":"Atı andıran yüz hatları."},{"w":"equinox","tr":"ekinoks / gün","te":"gece eşitliği","tt":"Noun","de":"İsim","dt":"The time or date (twice each year) at which the sun crosses the celestial equator, when day and night are of equal length","e1":"Güneşin gök ekvatorunu kestiği, gece ve gündüzün eşit olduğu tarih (yılda iki kez)","e1t":"The spring equinox (March 21).","e2":"Bahar ekinoksu.","e2t":"The autumn equinox (September 23)."},{"w":"equipoise","tr":"denge / ağırlık dengesi / muvazene","te":"Noun","tt":"İsim","de":"Balance of forces or interests","dt":"Güçlerin veya çıkarların dengesi","e1":"A state of political equipoise.","e1t":"Siyasi denge hali.","e2":"The equipoise of the scales.","e2t":"Terazinin dengesi."},{"w":"equity","tr":"hakkaniyet / adalet / öz sermaye / hisse senedi","te":"Noun","tt":"İsim","de":"The quality of being fair and impartial; or the value of shares issued by a company","dt":"Adil olma niteliği (hakkaniyet); veya bir şirketin hisse değeri/öz sermayesi","e1":"To act with equity and justice.","e1t":"Hakkaniyet ve adaletle hareket etmek.","e2":"Brand equity.","e2t":"Marka değeri."},{"w":"equivocate","tr":"kaçamak cevap vermek / lafı dolandırmak","te":"Verb","tt":"Fiil","de":"Use ambiguous language so as to conceal the truth or avoid committing oneself","dt":"Gerçeği gizlemek veya bir söz vermekten kaçınmak için belirsiz bir dil kullanmak","e1":"Stop equivocating and give me a straight answer!","e1t":"Lafı dolandırmayı bırak ve bana net bir cevap ver!","e2":"Equivocation (noun).","e2t":"Kaçamak konuşma."},{"w":"eremite","tr":"münzevi / çileci keşiş","te":"Noun","tt":"İsim","de":"A Christian hermit or recluse","dt":"(Hristiyanlıkta) toplumdan uzak yaşayan münzevi keşiş","e1":"The life of an eremite.","e1t":"Bir münzevinin hayatı.","e2":"(Not: 'Hermit' daha yaygındır).","e2t":""},{"w":"erode","tr":"aşındırmak / sarsmak / yavaşça yok etmek","te":"Verb","tt":"Fiil","de":"(Of wind, water, or other natural agents) gradually wear away (soil, rock, or land); or to gradually destroy","dt":"(Doğal etkenlerin) toprağı/kayayı aşındırması; veya (gücü/değeri) yavaşça azaltmak","e1":"The sea is eroding the coastline.","e1t":"Deniz kıyı şeridini aşındırıyor.","e2":"Inflation is eroding our savings.","e2t":"Enflasyon tasarruflarımızı eritiyor."},{"w":"errant","tr":"yoldan sapmış / hatalı / gezgin (şövalye)","te":"Adjective","tt":"Sıfat","de":"Erring or straying from the proper course or standards; or traveling in search of adventure","dt":"Doğru yoldan veya standartlardan sapmış; veya macera arayan","e1":"An errant husband.","e1t":"Sadakatsiz (yoldan sapmış) koca.","e2":"Errant thoughts.","e2t":"Başıboş (dalıp giden) düşünceler."},{"w":"escapade","tr":"macera / kaçamak / çılgınlık","te":"Noun","tt":"İsim","de":"An act or incident involving excitement, daring, or adventure","dt":"Heyecan veya macera içeren olay/hareket","e1":"A youthful escapade.","e1t":"Gençlik macerası (kaçamağı).","e2":"Their escapades in Paris.","e2t":"Paris'teki maceraları."},{"w":"espionage","tr":"casusluk","te":"Noun","tt":"İsim","de":"The practice of spying or of using spies, typically by governments to obtain political and military information","dt":"Genellikle hükümetlerin bilgi toplamak için yürüttüğü casusluk faaliyeti","e1":"Industrial espionage.","e1t":"Sanayi casusluğu.","e2":"To be accused of espionage.","e2t":"Casuslukla suçlanmak."},{"w":"esprit","tr":"ruh / canlılık / zeka","te":"Noun","tt":"İsim","de":"The quality of being lively, vivacious, or witty","dt":"Canlılık veya nüktedanlık (ruh)","e1":"Esprit de corps (team spirit).","e1t":"Ekip ruhu / Dayanışma duygusu.","e2":"Full of esprit.","e2t":"Hayat dolu / Nüktedan."},{"w":"estimable","tr":"saygıdeğer / takdire şayan","te":"Adjective","tt":"Sıfat","de":"Worthy of great respect","dt":"Büyük saygıyı hak eden","e1":"An estimable opponent.","e1t":"Saygıdeğer bir rakip.","e2":"Estimable qualities.","e2t":"Takdire şayan nitelikler."},{"w":"estranged","tr":"yabancılaşmış / ayrı yaşayan (eş) / uzaklaşmış","te":"Adjective","tt":"Sıfat","de":"(Of a person) no longer close or affectionate to someone; alienated","dt":"Biriyle artık yakın olmayan (soğumuş); yabancılaşmış","e1":"His estranged wife.","e1t":"Ayrı yaşadığı karısı.","e2":"To feel estranged from one's family.","e2t":"Ailesine yabancılaşmış hissetmek."},{"w":"ethereal / etherial","tr":"eterik / ruhani / göksel / uçucu","te":"Adjective","tt":"Sıfat","de":"Extremely light and delicate in a way that seems too perfect for this world","dt":"Bu dünya için fazla mükemmel görünecek kadar hafif ve narin","e1":"Ethereal beauty.","e1t":"Ruhani (eşsiz) bir güzellik.","e2":"Ethereal music.","e2t":"Göksel (hafif ve uçucu) müzik."},{"w":"etymology","tr":"etimoloji / kökenbilim","te":"Noun","tt":"İsim","de":"The study of the origin of words and the way in which their meanings have changed throughout history","dt":"Kelimelerin kökenini ve tarih içindeki anlam değişimlerini inceleyen bilim dalı","e1":"To trace the etymology of a word back to Latin.","e1t":"Bir kelimenin etimolojisini Latinceye kadar takip etmek.","e2":"Folk etymology.","e2t":"Halk etimolojisi."},{"w":"eugenics","tr":"öjeni / soy ıslahı","te":"Noun","tt":"İsim","de":"The study of how to arrange reproduction within a human population to increase the occurrence of heritable characteristics regarded as desirable","dt":"İstenen kalıtsal özelliklerin artırılması için insan nüfusunun kontrollü çoğaltılması çalışması","e1":"The controversial history of eugenics.","e1t":"Öjeninin tartışmalı tarihi.","e2":"Eugenics movement.","e2t":"Öjeni hareketi."},{"w":"eulogize / eulogise","tr":"övmek / methiye düzmek","te":"Verb","tt":"Fiil","de":"Praise highly in speech or writing","dt":"Birini konuşma veya yazıda yere göğe sığdıramamak (öve öve bitirememek)","e1":"He was eulogized as a hero.","e1t":"Bir kahraman olarak yüceltildi (övüldü).","e2":"Eulogy (noun).","e2t":"Methiye / Cenaze konuşması."},{"w":"euphony","tr":"kulağa hoş gelme / ahenk","te":"Noun","tt":"İsim","de":"The quality of being pleasing to the ear, especially through a harmonious combination of words","dt":"Özellikle kelimelerin uyumlu birleşimiyle sağlanan ses güzelliği","e1":"The euphony of his poetry.","e1t":"Şiirinin ses ahengi (kulağa hoş gelişi).","e2":"Euphonious (adjective).","e2t":"Ahenkli / Tatlı sesli. (Not: 'Cacophony' zıttıdır)."},{"w":"euphoria","tr":"öfori / aşırı mutluluk ve zindelik hissi","te":"Noun","tt":"İsim","de":"A feeling or state of intense excitement and happiness","dt":"Yoğun bir heyecan, mutluluk ve esenlik hali","e1":"The euphoria of winning the gold medal.","e1t":"Altın madalya kazanmanın yarattığı aşırı mutluluk hissi.","e2":"Euphoric (adjective).","e2t":"Kendinden geçmiş / Çok mutlu."},{"w":"euthanasia","tr":"ötanazi","te":"Noun","tt":"İsim","de":"The painless killing of a patient suffering from an incurable and painful disease","dt":"İyileşmez ve acı verici bir hastalığı olan hastanın acısız şekilde hayatına son verilmesi","e1":"The legal and ethical debate over euthanasia.","e1t":"Ötanazi üzerine yasal ve etik tartışmalar.","e2":"Passive euthanasia.","e2t":"Pasif ötanazi."},{"w":"evenhanded / even","tr":"handed","te":"adil / tarafsız / herkese eşit davranan","tt":"Adjective","de":"Sıfat","dt":"Fair and impartial in treatment or judgment","e1":"Muamele veya yargıda adil ve tarafsız","e1t":"An evenhanded approach to the problem.","e2":"Soruna adil (tarafsız) bir yaklaşım.","e2t":"He is known for his evenhanded leadership."},{"w":"evict","tr":"(evden/topraktan) çıkarmak / tahliye ettirmek","te":"Verb","tt":"Fiil","de":"Expel (someone) from a property, especially with the support of the law","dt":"Birini (özellikle yasal yolla) mülkten çıkarmak","e1":"They were evicted for non","e1t":"payment of rent.","e2":"Kirayı ödemedikleri için evden çıkarıldılar.","e2t":"Eviction (noun)."},{"w":"evince","tr":"göstermek / belli etmek / kanıtı olmak","te":"Verb","tt":"Fiil","de":"Reveal the presence of (a quality or feeling); indicate","dt":"(Bir duygu veya niteliği) açığa vurmak veya belli etmek","e1":"He evinced no surprise at the news.","e1t":"Haberler karşısında hiçbir şaşkınlık belirtisi göstermedi.","e2":"To evince a great deal of interest.","e2t":"Büyük bir ilgi göstermek."},{"w":"evocative","tr":"çağrıştıran / uyandıran / hatırlatan","te":"Adjective","tt":"Sıfat","de":"Bringing strong images, memories, or feelings to mind","dt":"Zihinde güçlü imgeler, anılar veya duygular uyandıran","e1":"Music evocative of the sea.","e1t":"Denizi çağrıştıran müzik.","e2":"An evocative description.","e2t":"(Anıları) canlandıran bir betimleme."},{"w":"exceptional","tr":"istisnai / olağanüstü / nadir","te":"Adjective","tt":"Sıfat","de":"Unusually good; outstanding; or unusual","dt":"Sıra dışı derecede iyi; veya alışılmadık (istisnai)","e1":"A student of exceptional ability.","e1t":"Olağanüstü yetenekli bir öğrenci.","e2":"Exceptional circumstances.","e2t":"İstisnai durumlar."},{"w":"exchequer","tr":"hazine / maliye / devlet kasası","te":"Noun","tt":"Isim","de":"A royal or national treasury; or the government department in charge of public revenue","dt":"Devlet hazinesi veya maliyeden sorumlu bakanlık/daire","e1":"The Chancellor of the Exchequer (UK).","e1t":"(İngiltere'de) Maliye Bakanı.","e2":"To drain the exchequer.","e2t":"Devlet hazinesini tüketmek."},{"w":"exclaim","tr":"haykırmak / bağırmak (heyecanla/şaşkınlıkla)","te":"Verb","tt":"Fiil","de":"Cry out suddenly, especially in surprise, anger, or pain","dt":"Aniden (şaşkınlık, öfke veya acıyla) bağırmak","e1":"\"Look!\" she exclaimed.","e1t":"\"Bak!\" diye haykırdı.","e2":"To exclaim in surprise.","e2t":"Şaşkınlıkla bağırmak."},{"w":"exculpate","tr":"aklamak / suçsuzluğunu kanıtlamak","te":"Verb","tt":"Fiil","de":"Show or declare that (someone) is not guilty of wrongdoing","dt":"Birinin suçsuz olduğunu göstermek veya ilan etmek","e1":"New evidence helped to exculpate him.","e1t":"Yeni kanıtlar onun aklanmasına yardımcı oldu.","e2":"(Not: 'Acquit' daha yaygındır).","e2t":""},{"w":"execrable","tr":"iğrenç / berbat / lanetli","te":"Adjective","tt":"Sıfat","de":"Extremely bad or unpleasant","dt":"Son derece kötü veya nahoş","e1":"An execrable performance.","e1t":"Berbat (iğrenç) bir performans.","e2":"Execrable food.","e2t":"Yenilmeyecek kadar kötü yemek."},{"w":"exegesis","tr":"tefsir / yorum (metin üzerine)","te":"Noun","tt":"İsim","de":"Critical explanation or interpretation of a text, especially of scripture","dt":"Bir metnin (özellikle kutsal kitapların) eleştirel yorumu veya açıklaması","e1":"Biblical exegesis.","e1t":"İncil tefsiri (yorumu).","e2":"A detailed exegesis of the poem.","e2t":"Şiirin detaylı bir çözümlemesi."},{"w":"exemplify","tr":"örneklemek / timsali olmak","te":"Verb","tt":"Fiil","de":"Be a typical example of; or to illustrate by giving an example","dt":"Bir şeyin tipik örneği olmak; veya örnek vererek açıklamak","e1":"This story exemplifies the courage of the soldiers.","e1t":"Bu hikaye askerlerin cesaretini örnekliyor (temsil ediyor).","e2":"To exemplify a rule.","e2t":"Bir kuralı örneklerle göstermek."},{"w":"exhale","tr":"nefes vermek / dışarı solumak","te":"Verb","tt":"Fiil","de":"Breathe out in a deliberate manner","dt":"Kasten nefes vermek; soluk boşaltmak","e1":"To inhale and exhale.","e1t":"Nefes almak ve vermek.","e2":"The chimney exhaled smoke.","e2t":"Baca duman çıkardı (tüttü). (Not: 'Inhale'"},{"w":"exigency","tr":"aciliyet / zorunluluk / ihtiyaç","te":"Noun","tt":"İsim","de":"An urgent need or demand","dt":"Acil ihtiyaç veya talep","e1":"The exigencies of war.","e1t":"Savaşın getirdiği zorunluluklar.","e2":"To adapt to the exigency of the situation.","e2t":"Durumun aciliyetine uyum sağlamak."},{"w":"exiguous","tr":"çok az / yetersiz / cüzi","te":"Adjective","tt":"Sıfat","de":"Very small in size or amount","dt":"Miktar veya boyut olarak çok küçük (yetersiz)","e1":"An exiguous income.","e1t":"Çok kısıtlı (cüzi) bir gelir.","e2":"Exiguous resources.","e2t":"Yetersiz kaynaklar."},{"w":"exonerate","tr":"aklamak / suçsuz bulmak","te":"Verb","tt":"Fiil","de":"Absolve (someone) from blame for a fault or wrongdoing","dt":"Birini bir suç veya hatadan muaf tutmak/aklamak","e1":"The investigation exonerated the pilot.","e1t":"Soruşturma pilotu suçsuz buldu (akladı).","e2":"Exoneration (noun).","e2t":"Aklanma."},{"w":"exorcise / exorcize","tr":"(cin/şeytan) çıkarmak / (korkuyu) yenmek","te":"Verb","tt":"Fiil","de":"Drive out an evil spirit from (a person or place); or to rid oneself of a bad memory","dt":"Bir yerden veya kişiden kötü ruhları kovmak; veya kötü bir anıdan kurtulmak","e1":"To exorcise demons.","e1t":"Şeytan çıkarmak.","e2":"He tried to exorcise the ghosts of his past.","e2t":"Geçmişinin hayaletlerinden (kötü anılarından) kurtulmaya çalıştı."},{"w":"expansive","tr":"geniş / kapsamlı / cana yakın (kişi)","te":"Adjective","tt":"Sıfat","de":"Covering a wide area in terms of space or scope; or (of a person) outgoing and talkative","dt":"Geniş bir alanı veya kapsamı kaplayan; veya (kişi için) dışadönük ve konuşkan","e1":"Expansive views of the valley.","e1t":"Vadinin uçsuz buçsız manzaraları.","e2":"He was in an expansive mood.","e2t":"Çok neşeli ve konuşkan bir ruh halindeydi."},{"w":"expatiate","tr":"uzun uzadıya anlatmak / detaylandırmak","te":"Verb","tt":"Fiil","de":"Speak or write at length or in detail","dt":"Bir konu hakkında çok uzun konuşmak veya yazmak","e1":"She expatiated on the importance of education.","e1t":"Eğitimin önemi üzerine uzun uzadıya konuştu.","e2":"To expatiate on a favorite topic.","e2t":"Sevilen bir konuyu detaylandırmak."},{"w":"expiate","tr":"kefaret etmek / (günahını) ödemek","te":"Verb","tt":"Fiil","de":"Atone for (guilt or sin)","dt":"Bir günah veya suçun cezasını çekerek kendini affettirmek","e1":"To expiate a crime.","e1t":"Bir suçun kefaretini ödemek.","e2":"He tried to expiate his past errors by doing good deeds.","e2t":"İyi işler yaparak geçmiş hatalarını telafi etmeye çalıştı."},{"w":"expletive","tr":"küfür / nida / dolgu kelimesi","te":"Noun","tt":"İsim","de":"An oath or swear word; or a word used to fill out a sentence without adding meaning","dt":"Küfür veya sövgü; veya cümlede anlamı olmayan dolgu kelimesi","e1":"He uttered a series of expletives.","e1t":"Bir dizi küfür savurdu.","e2":"Expletives deleted (in a transcript).","e2t":"(Metinde) küfürler çıkarılmıştır."},{"w":"explicate","tr":"açıklamak / çözümlemek / izah etmek","te":"Verb","tt":"Fiil","de":"Analyze and develop (an idea or principle) in detail","dt":"Bir fikri veya ilkeyi detaylıca analiz etmek ve açıklamak","e1":"To explicate a complex poem.","e1t":"Karmaşık bir şiiri çözümlemek.","e2":"Explication (noun).","e2t":"Detaylı açıklama."},{"w":"expository","tr":"açıklayıcı / izah edici","te":"Adjective","tt":"Sıfat","de":"Intended to explain or describe something","dt":"Bir şeyi açıklamayı veya tarif etmeyi amaçlayan","e1":"An expository essay.","e1t":"Açıklayıcı bir makale.","e2":"Expository writing.","e2t":"Bilgi verici yazı."},{"w":"expostulation","tr":"itiraz / sitem / uyarı","te":"Noun","tt":"İsim","de":"An expression of strong disapproval or disagreement; a protest","dt":"Güçlü bir onaylamama veya itiraz ifadesi","e1":"Despite my expostulations, he went anyway.","e1t":"Tüm itirazlarıma (sitemlerime) rağmen yine de gitti.","e2":"Expostulate (verb).","e2t":"İtiraz etmek / Akıl vermek."},{"w":"expropriate","tr":"kamulaştırmak / el koymak","te":"Verb","tt":"Fiil","de":"(Of the state) take property from its owner for public use or benefit","dt":"(Devletin) kamu yararı için bir mülke el koyması","e1":"The government expropriated the land to build a road.","e1t":"Hükümet yol yapmak için toprağı kamulaştırdı.","e2":"Expropriation (noun).","e2t":"Kamulaştırma."},{"w":"expunge","tr":"silmek / yok etmek / (kayıttan) çıkarmak","te":"Verb","tt":"Fiil","de":"Obliterate or remove completely (something unwanted or unpleasant)","dt":"İstenmeyen bir şeyi tamamen silmek veya yok etmek","e1":"To expunge a name from a list.","e1t":"Bir ismi listeden silmek.","e2":"He wanted to expunge the memory of that day.","e2t":"O günün anısını silip atmak istiyordu."},{"w":"expurgate","tr":"(kitap vb.) sakıncalı kısımları çıkarmak / ayıklamak","te":"Verb","tt":"Fiil","de":"Remove matter thought to be objectionable or unsuitable from a book or account","dt":"Bir kitaptan veya metinden uygunsuz kısımları temizlemek","e1":"An expurgated edition of the novel.","e1t":"Romanın (sansürlenmiş/temizlenmiş) baskısı. (Not: 'Bowdlerize' ile benzerdir).","e2":"","e2t":""},{"w":"extemporaneous","tr":"hazırlıksız / irticalen","te":"Adjective","tt":"Sıfat","de":"Spoken or done without preparation","dt":"Hazırlık yapmadan (o anki ilhamla) söylenen veya yapılan","e1":"An extemporaneous speech.","e1t":"Hazırlıksız (doğaçlama) bir konuşma.","e2":"Extempore (adverb/adj).","e2t":"Hazırlıksız."},{"w":"extenuate","tr":"hafifletmek / (suçu) azaltmak","te":"Verb","tt":"Fiil","de":"Cause (an offense) to seem less serious","dt":"Bir suçun daha az ciddi görünmesini sağlamak (hafifletici neden sunmak)","e1":"Extenuating circumstances.","e1t":"Hafifletici sebepler.","e2":"Nothing can extenuate such a crime.","e2t":"Hiçbir şey böyle bir suçu hafifletemez."},{"w":"exterminate","tr":"yok etmek / kökünü kazımak / imha etmek","te":"Verb","tt":"Fiil","de":"Destroy completely","dt":"Tamamen yok etmek (itlaf etmek)","e1":"To exterminate rats.","e1t":"Fareleri itlaf etmek.","e2":"The invaders tried to exterminate the local population.","e2t":"İstilacılar yerel halkın kökünü kazımaya çalıştı."},{"w":"extirpate","tr":"kökünden sökmek / tamamen yok etmek","te":"Verb","tt":"Fiil","de":"Root out and destroy completely","dt":"Kökünü kazıyıp tamamen ortadan kaldırmak","e1":"To extirpate a disease.","e1t":"Bir hastalığı tamamen yok etmek.","e2":"The use of force to extirpate the rebellion.","e2t":"İsyanı kökünden kazımak için güç kullanımı."},{"w":"extort","tr":"şantajla/zorla almak / haraç kesmek","te":"Verb","tt":"Fiil","de":"Obtain (something, especially money) through force, threats, or unfair power","dt":"Güç veya tehdit kullanarak (para vb.) elde etmek","e1":"To extort money from someone.","e1t":"Birinden zorla para almak.","e2":"He was convicted of extortion.","e2t":"Haraç kesmekten (şantajdan) suçlu bulundu."},{"w":"extraction","tr":"çekip çıkarma / köken / soy","te":"Noun","tt":"İsim","de":"The action of taking out something, especially using effort or force; or lineage","dt":"Bir şeyi çekip çıkarma; veya soy/köken","e1":"Tooth extraction.","e1t":"Diş çekimi.","e2":"The extraction of oil from the ground.","e2t":"Petrolün yerden çıkarılması."},{"w":"extrapolate","tr":"verilerden sonuç çıkarmak / öngörmek","te":"Verb","tt":"Fiil","de":"Extend the application of (a method or conclusion) to an unknown situation by assuming that existing trends will continue","dt":"Mevcut trendlerin süreceğini varsayarak bilinmeyen durumlar için tahmin yürütmek","e1":"To extrapolate future trends from past data.","e1t":"Geçmiş verilerden gelecekteki eğilimleri öngörmek.","e2":"Extrapolation (noun).","e2t":"Mevcut veriden sonuç çıkarma."},{"w":"extravagance","tr":"müsriflik / aşırılık / savurganlık","te":"Noun","tt":"İsim","de":"Lack of restraint in spending money or use of resources; or an excessive action","dt":"Para veya kaynak kullanımında aşırılık; savurganlık","e1":"The extravagance of the royal court.","e1t":"Kraliyet sarayının ihtişamı ve müsrifliği.","e2":"To regret your earlier extravagances.","e2t":"Daha önceki savurganlıklarından pişman olmak."},{"w":"extricate","tr":"kurtarmak / (zor durumdan) çıkarmak","te":"Verb","tt":"Fiil","de":"Free (someone or something) from a constraint or difficulty","dt":"Birini bir zorluktan veya engelden kurtarmak (çıkarmak)","e1":"To extricate yourself from a difficult situation.","e1t":"Kendini zor bir durumdan kurtarmak.","e2":"They extricated the victims from the wreckage.","e2t":"Kurbanları enkazdan çıkardılar."},{"w":"extrinsic","tr":"dışsal / dıştan gelen / asli olmayan","te":"Adjective","tt":"Sıfat","de":"Not part of the essential nature of someone or something; coming or derived from outside","dt":"Bir şeyin özünde olmayan; dışarıdan gelen","e1":"Extrinsic factors.","e1t":"Dış etkenler.","e2":"Extrinsic motivation (rewards).","e2t":"Dışsal motivasyon (ödül vb.). (Not: 'Intrinsic'"},{"w":"extrovert / extravert","tr":"dışadönük kişi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An outgoing, socially confident person","dt":"Sosyal, dışadönük ve kendine güvenen kişi","e1":"He is a natural extrovert.","e1t":"O doğuştan dışadönük biridir.","e2":"Extroverted behavior.","e2t":"Dışadönük davranış."},{"w":"extrude","tr":"(kalıptan) basmak / fışkırtmak / dışarı atmak","te":"Verb","tt":"Fiil","de":"Thrust or force out; or shape by forcing through a die","dt":"Dışarı fırlatmak; veya (metal/plastik vb.) bir kalıptan geçirerek şekil vermek","e1":"Extruded plastic pipes.","e1t":"Kalıptan çekilmiş plastik borular.","e2":"Lava was extruded from the volcano.","e2t":"Yanardağdan lav fışkırdı."},{"w":"exuberance","tr":"coşku / canlılık / bereket","te":"Noun","tt":"İsim","de":"The quality of being full of energy, excitement, and cheerfulness; or profusion","dt":"Enerji, heyecan ve neşe dolu olma niteliği; veya bolluk","e1":"Youthful exuberance.","e1t":"Gençlik coşkusu.","e2":"The exuberance of the tropical forest.","e2t":"Tropikal ormanın gürlüğü (bereketi)."},{"w":"exult","tr":"çok sevinmek / sevinçten uçmak","te":"Verb","tt":"Fiil","de":"Feel or show triumphant elation or jubilation","dt":"Büyük bir başarı sonrası sevinç ve zafer sarhoşluğu yaşamak","e1":"To exult in your victory.","e1t":"Zaferinden dolayı çok sevinmek.","e2":"Exultant (adjective).","e2t":"Çok sevinçli / Zafer kazanmış."},{"w":"facet","tr":"taraf / yön / (elmas) yüzey","te":"Noun","tt":"Isim","de":"One side of something many","dt":"sided, especially of a cut gem; or a particular aspect of something","e1":"Çok taraflı bir şeyin (özellikle mücevherin) bir yüzü; veya bir meselenin bir yönü","e1t":"To examine every facet of the problem.","e2":"Problemin her yönünü incelemek.","e2t":"The facets of a diamond."},{"w":"facsimile","tr":"tıpkıbasım / faks / kopya","te":"Noun","tt":"İsim","de":"An exact copy, especially of written or printed material","dt":"Özellikle yazılı veya basılı bir materyalin birebir kopyası","e1":"A facsimile of the original document.","e1t":"Orijinal belgenin tıpkıbasımı. (Not: 'Fax' kelimesi buradan türetilmiştir).","e2":"","e2t":""},{"w":"factitious","tr":"yapay / düzmece / doğal olmayan","te":"Adjective","tt":"Sıfat","de":"Artificially created or developed","dt":"Yapay olarak oluşturulmuş veya geliştirilmiş","e1":"A factitious demand for the product.","e1t":"Ürün için (reklamlarla yaratılan) yapay talep.","e2":"Factitious disorder (medicine).","e2t":"Yapay bozukluk (hastalık taklidi)."},{"w":"factotum","tr":"her işe koşan kimse / ayak işlerine bakan","te":"Noun","tt":"İsim","de":"A person employed to do all types of work","dt":"Her türlü işi yapmak üzere istihdam edilen kişi","e1":"He was the director's personal factotum.","e1t":"Müdürün her işine koşan (sağ kolu) yardımcısıydı.","e2":"To work as a general factotum on a farm.","e2t":"Bir çiftlikte her işe bakan yardımcı olarak çalışmak."},{"w":"fallacious","tr":"yanıltıcı / mantıksız / safsata içeren","te":"Adjective","tt":"Sıfat","de":"Based on a mistaken belief; misleading","dt":"Yanlış bir inanca dayalı; yanıltıcı","e1":"A fallacious argument.","e1t":"Mantıksız (safsata dolu) bir argüman.","e2":"Fallacious reasoning.","e2t":"Yanıltıcı akıl yürütme."},{"w":"fallow","tr":"nadasa bırakılmış / işlenmemiş","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of farmland) plowed and left unseeded for a season or more; or inactive","dt":"(Tarım arazisi için) sürülmüş fakat ekilmemiş; veya hareketsiz","e1":"To leave the land fallow.","e1t":"Toprağı nadasa bırakmak.","e2":"A fallow period in his career.","e2t":"Kariyerindeki verimsiz (durgun) bir dönem."},{"w":"falsify","tr":"tahrif etmek / üzerinde oynamak / çürütmek","te":"Verb","tt":"Fiil","de":"Alter (information or a document) so as to mislead; or to prove to be false","dt":"Yanıltmak amacıyla (bilgi/belge) üzerinde değişiklik yapmak; veya bir şeyin yanlışlığını kanıtlamak","e1":"To falsify medical records.","e1t":"Tıbbi kayıtlar üzerinde tahrifat yapmak.","e2":"To falsify a theory.","e2t":"Bir teoriyi çürütmek."},{"w":"fanaticism","tr":"fanatiklik / bağnazlık / aşırılık","te":"Noun","tt":"İsim","de":"The quality of being fanatical; obsessive enthusiasm","dt":"Bir konuda aşırı, takıntılı ve ödün vermez olma durumu","e1":"Religious fanaticism.","e1t":"Dini bağnazlık.","e2":"To avoid political fanaticism.","e2t":"Siyasi aşırılıktan kaçınmak."},{"w":"fancied","tr":"hayali / varsayılan / sevilen","te":"Adjective","tt":"Sıfat","de":"Existing only in the imagination; or highly regarded","dt":"Sadece hayal gücünde var olan; veya çok beğenilen","e1":"Fancied grievances.","e1t":"Hayali (uydurma) şikayetler.","e2":"The fancied horse (in racing).","e2t":"(Yarışta) favori gösterilen at."},{"w":"fancier","tr":"meraklı / yetiştirici / uzman","te":"Noun","tt":"İsim","de":"A person who has a specialized interest in something, especially domestic animals","dt":"Bir şeye (özellikle evcil hayvanlara) özel ilgisi olan veya yetiştiren kişi","e1":"A pigeon fancier.","e1t":"Güvercin meraklısı (yetiştiricisi).","e2":"Dog fancier.","e2t":"Köpek uzmanı/meraklısı."},{"w":"fanciful","tr":"hayalperest / hayali / abartılı","te":"Adjective","tt":"Sıfat","de":"(Of a person) over","dt":"imaginative and unrealistic; or existing only in the imagination","e1":"Hayalperest ve gerçek dışı; veya hayal ürünü","e1t":"A fanciful story.","e2":"Hayal ürünü bir hikaye.","e2t":"Fanciful designs."},{"w":"fanfare","tr":"boru sesi / tantana / görkemli ilan","te":"Noun","tt":"İsim","de":"A short ceremonial tune played on brass instruments; or elaborate activities to attract attention","dt":"Boruyla çalınan törensel kısa melodi; veya dikkat çekmek için yapılan büyük tantana","e1":"A fanfare of trumpets.","e1t":"Trompet sesleri.","e2":"The new product was launched with much fanfare.","e2t":"Yeni ürün büyük bir tantanayla (görkemle) tanıtıldı."},{"w":"farce","tr":"fars / komedi / maskaralık","te":"Noun","tt":"İsim","de":"A comic dramatic work using buffoonery and horseplay; or an absurd event","dt":"Kaba komedi unsurları içeren tiyatro oyunu; veya saçma/gülünç olay","e1":"The trial was a total farce.","e1t":"Duruşma tam bir maskaralıktı (tiyatroydu).","e2":"A bedroom farce.","e2t":"Hafif ve komik tiyatro oyunu."},{"w":"fatalism","tr":"fatalizm / kadercilik","te":"Noun","tt":"İsim","de":"The belief that all events are predetermined and therefore inevitable","dt":"Tüm olayların önceden belirlendiği ve kaçınılmaz olduğu inancı","e1":"A sense of fatalism.","e1t":"Kadercilik duygusu.","e2":"Fatalistic (adjective).","e2t":"Kaderci."},{"w":"fauna","tr":"fauna / bölge hayvanları","te":"Noun","tt":"İsim","de":"The animals of a particular region, habitat, or geological period","dt":"Belirli bir bölgeye veya döneme ait hayvan varlığı","e1":"The flora and fauna of the Amazon.","e1t":"Amazon'un bitki ve hayvan varlığı.","e2":"Marine fauna.","e2t":"Deniz canlıları. (Not: 'Flora'"},{"w":"fawning","tr":"dalkavukluk yapan / yaltaklanan","te":"Adjective","tt":"Sıfat","de":"Displaying exaggerated flattery or affection; obsequious","dt":"Aşırı övgü veya sevgi göstererek yaltaklanan","e1":"A fawning assistant.","e1t":"Dalkavuk bir yardımcı.","e2":"To grow tired of his fawning behavior.","e2t":"Onun yaltaklanan tavırlarından bıkmak."},{"w":"faze","tr":"rahatsız etmek / endişelendirmek / güvenini sarsmak","te":"Verb","tt":"Fiil","de":"Disturb or disconcert (someone)","dt":"Birini rahatsız etmek veya kendinden emin halini bozmak","e1":"Nothing seems to faze him.","e1t":"Hiçbir şey onu endişelendirmiyor (istifini bozmuyor) gibi görünüyor.","e2":"She wasn't fazed by the criticism.","e2t":"Eleştirilerden etkilenmedi (moralini bozmadı). (Not: 'Phase'"},{"w":"febrile","tr":"ateşli / hummalı / heyecanlı","te":"Adjective","tt":"Sıfat","de":"Having or showing the symptoms of a fever; or characterized by a great deal of nervous excitement","dt":"Ateşli (hastalık); veya aşırı heyecan ve gerginlik içeren","e1":"A febrile condition.","e1t":"Ateşli bir durum.","e2":"The febrile atmosphere before the election.","e2t":"Seçim öncesindeki hummalı (gergin) ortam."},{"w":"fecundity","tr":"verimlilik / doğurganlık / bereket","te":"Noun","tt":"İsim","de":"The ability to produce an abundance of offspring or new growth; fertility","dt":"Çok sayıda yavru veya yeni oluşum üretme yeteneği; bereket","e1":"The fecundity of his imagination.","e1t":"Hayal gücünün zenginliği (üretkenliği).","e2":"Land of great fecundity.","e2t":"Çok verimli (bereketli) toprak."},{"w":"feint","tr":"şaşırtmaca / aldatıcı hareket / feint","te":"Noun/Verb","tt":"İsim/Fiil","de":"A deceptive or pretended blow, thrust, or other movement, especially in boxing or fencing","dt":"Özellikle boks veya eskrimde rakibi şaşırtmak için yapılan sahte hamle","e1":"He made a feint to the left.","e1t":"Sola doğru bir şaşırtmaca yaptı.","e2":"A feint attack.","e2t":"Aldatıcı (yalancı) saldırı."},{"w":"felicitous","tr":"uygun / yerinde / mutlu","te":"Adjective","tt":"Sıfat","de":"Well chosen or suited to the circumstances; or pleasing and fortunate","dt":"Mevcut duruma çok uygun (tam isabet); veya mutluluk verici","e1":"A felicitous remark.","e1t":"Çok yerinde (uygun) bir söz.","e2":"A felicitous marriage.","e2t":"Mutlu bir evlilik."},{"w":"feline","tr":"kedigillerden / kedi gibi / sinsi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to or affecting cats or other members of the cat family","dt":"Kedilerle veya kedi ailesiyle ilgili; kedi gibi (çevik/sinsi)","e1":"Feline grace.","e1t":"Kedi gibi (zarif) hareketler.","e2":"The feline population.","e2t":"Kedi nüfusu."},{"w":"fell","tr":"kesmek (ağaç) / yere sermek / zalim / tepe","te":"Verb/Adj/Noun","tt":"To cut down a tree; or to knock someone down; or (literary) cruel and terrible","de":"Ağaç kesmek; veya (birini) yere sermek; veya (edebi) zalim/korkunç","dt":"To fell an oak tree.","e1":"Bir meşe ağacını kesmek (devirmek).","e1t":"With one fell swoop (idiom: bir hamlede).","e2":"","e2t":""},{"w":"felon","tr":"suçlu / mahkum (ağır suç)","te":"Noun","tt":"İsim","de":"A person who has been convicted of a felony","dt":"Ağır bir suçtan hüküm giymiş kişi","e1":"A convicted felon.","e1t":"Sabıkalı ağır suçlu.","e2":"Felony (noun).","e2t":"Ağır suç."},{"w":"feral","tr":"yabani / vahşileşmiş","te":"Adjective","tt":"Sıfat","de":"(Especially of an animal) in a wild state, especially after escape from captivity","dt":"(Özellikle bir hayvan için) evcillikten çıkıp vahşileşmiş","e1":"Feral cats.","e1t":"Yabanileşmiş (sokak) kedileri.","e2":"A feral child.","e2t":"Doğada (vahşi ortamda) büyümüş çocuk."},{"w":"ferment","tr":"mayalanmak / kışkırtmak / kargaşa","te":"Verb/Noun","tt":"Fiil/İsim","de":"To undergo fermentation; or to incite or stir up trouble","dt":"Mayalanmak; veya (sorun/isyan) kışkırtmak; kargaşa","e1":"The wine is left to ferment.","e1t":"Şarap mayalanmaya bırakılır.","e2":"Political ferment.","e2t":"Siyasi kargaşa (kaynama)."},{"w":"ferret","tr":"gelincik / araştırıp bulmak / deşelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small domesticated polecat used for catching rabbits; or to search tenaciously","dt":"Evcil gelincik; veya (bir şeyi) didik didik arayıp bulmak","e1":"To ferret out the truth.","e1t":"Gerçeği deşeleyip (araştırıp) ortaya çıkarmak.","e2":"He managed to ferret out the secret.","e2t":"Sırrı bulup çıkarmayı başardı."},{"w":"fervid","tr":"ateşli / çok sıcak / coşkulu","te":"Adjective","tt":"Sıfat","de":"Intensively enthusiastic or passionate, especially to an excessive degree","dt":"Aşırı derecede ateşli veya tutkulu","e1":"Fervid imagination.","e1t":"Ateşli hayal gücü.","e2":"Fervid heat.","e2t":"Yakıcı sıcaklık."},{"w":"fete / fête","tr":"festival / panayır / şerefine eğlence düzenlemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A celebration or festival; or to honor or entertain someone lavishly","dt":"Kutlama veya panayır; veya birini görkemli bir şekilde ağırlamak/onurlandırmak","e1":"The village fete.","e1t":"Köy festivali.","e2":"He was feted as a hero upon his return.","e2t":"Dönüşünde bir kahraman gibi ağırlandı (onurlandırıldı)."},{"w":"fetish / fetiş","tr":"fetiş / uğur / aşırı tutku","te":"Noun","tt":"İsim","de":"An object believed to have magical powers; or a form of sexual desire; or an excessive commitment","dt":"Büyülü güçleri olduğuna inanılan nesne; veya cinsel tutku (fetiş); veya bir şeye aşırı düşkünlük","e1":"To make a fetish of efficiency.","e1t":"Verimliliği saplantı (fetiş) haline getirmek.","e2":"","e2t":""},{"w":"fetter","tr":"pranga / köstek / kısıtlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A chain or shackle placed on the feet; or a restraint or check on someone's freedom","dt":"Ayak prangası; veya özgürlüğü kısıtlayan engel","e1":"To be bound by the fetters of tradition.","e1t":"Geleneğin zincirleriyle (bağlarıyla) kısıtlanmış olmak.","e2":"Poverty fettered his progress.","e2t":"Yoksulluk onun ilerlemesine engel (köstek) oldu."},{"w":"fiat","tr":"emir / ferman / kararname","te":"Noun","tt":"İsim","de":"A formal authorization or proposition; an arbitrary order","dt":"Resmi izin veya yetki; veya keyfi emir","e1":"To rule by fiat.","e1t":"Kararnamelerle (fermanla) yönetmek.","e2":"Fiat money (currency not backed by a commodity).","e2t":"İtibari para (altın karşılığı olmayan devlet garantili para)."},{"w":"fictitious","tr":"hayali / uydurma / kurgusal","te":"Adjective","tt":"Sıfat","de":"Not real or true; imaginary or fabricated","dt":"Gerçek olmayan; uydurma veya kurgusal","e1":"A fictitious name.","e1t":"Uydurma (takma) isim.","e2":"Fictitious characters in a novel.","e2t":"Bir romandaki kurgusal karakterler."},{"w":"figment","tr":"uydurma / hayal ürünü","te":"Noun","tt":"İsim","de":"A thing that someone believes to be real but that exists only in their imagination","dt":"Birinin gerçek sandığı ama sadece hayalinde var olan şey","e1":"A figment of your imagination.","e1t":"Senin hayalinin bir ürünü (uydurması).","e2":"","e2t":""},{"w":"figurehead","tr":"sembolik lider / kukla başkan / gemi başı heykeli","te":"Noun","tt":"İsim","de":"A nominal leader or head without real power; or a carving on the bow of a ship","dt":"Gerçek gücü olmayan kağıt üzerindeki lider; veya gemi burnundaki oyma heykel","e1":"The king is just a figurehead; the prime minister holds the real power.","e1t":"Kral sadece sembolik bir liderdir; gerçek güç başbakandadır.","e2":"A carved figurehead.","e2t":"Gemi başı heykeli."},{"w":"figurine","tr":"biblo / heykelcik","te":"Noun","tt":"İsim","de":"A statuette, especially one of a human form","dt":"Özellikle insan formundaki küçük heykelcik","e1":"Porcelain figurines.","e1t":"Porselen biblolar.","e2":"Ancient clay figurines.","e2t":"Antik kilden heykelcikler."},{"w":"filch","tr":"aşırmak / çalmak (ufak tefek şeyleri)","te":"Verb","tt":"Fiil","de":"Pilfer or steal (something, especially a thing of small value) in a casual way","dt":"Değersiz şeyleri gizlice ve çabucak çalmak","e1":"He filched a bar of chocolate from the shop.","e1t":"Dükkandan bir çikolata aşırdı.","e2":"To filch someone's ideas.","e2t":"Birinin fikirlerini (gizlice) çalmak."},{"w":"filigree","tr":"telkari / ince gümüş işleme","te":"Noun","tt":"İsim","de":"Ornamental work of fine wire formed into delicate tracery","dt":"İnce metal tellerin işlenmesiyle yapılan süsleme sanatı","e1":"A silver filigree brooch.","e1t":"Gümüş telkari bir broş.","e2":"Filigree earrings.","e2t":"Telkari küpeler."},{"w":"filing","tr":"dosyalama / talaş / başvuruda bulunma","te":"Noun","tt":"İsim","de":"The process of storing documents; or a small particle of metal","dt":"Belge depolama süreci; veya metal tozları (talaş)","e1":"To keep up with the office filing.","e1t":"Ofis dosyalama işlerine yetişmek.","e2":"Iron filings (physics).","e2t":"Demir tozları."},{"w":"finale","tr":"final / bitiş / sonuç","te":"Noun","tt":"İsim","de":"The last part of a piece of music, an entertainment, or a public event","dt":"Bir müzik parçasının veya gösterinin son bölümü","e1":"A grand finale.","e1t":"Görkemli bir final.","e2":"The season finale of a TV show.","e2t":"Bir dizinin sezon finali."},{"w":"finite","tr":"sınırlı / sonu olan","te":"Adjective","tt":"Sıfat","de":"Having limits or bounds; not infinite","dt":"Sınırları olan; sonsuz olmayan","e1":"The world's resources are finite.","e1t":"Dünyanın kaynakları sınırlıdır.","e2":"A finite number of possibilities.","e2t":"Sınırlı sayıda olasılık. (Not: 'Infinite'"},{"w":"firebrand","tr":"kundakçı / kışkırtıcı / ele avuca sığmaz kimse","te":"Noun","tt":"İsim","de":"A person who is passionate about a particular cause, typically inciting change and taking radical action","dt":"Değişim için insanları kışkırtan, ateşli ve radikal kişi","e1":"A political firebrand.","e1t":"Siyasi bir kışkırtıcı (ateşli lider).","e2":"A young firebrand in the protest.","e2t":"Protestodaki ateşli genç."},{"w":"fitful","tr":"düzensiz / kesik kesik / aralıklı","te":"Adjective","tt":"Sıfat","de":"Not regular or steady; occurring intermittently","dt":"Düzenli olmayan; zaman zaman gerçekleşen","e1":"A fitful sleep.","e1t":"Bölük pörçük (düzensiz) uyku.","e2":"Fitful energy.","e2t":"Bir gelip bir giden enerji."},{"w":"flabbergasted","tr":"hayretler içinde kalmış / şaşkınlıktan dili tutulmuş","te":"Adjective","tt":"Sıfat","de":"Greatly surprised; astonished","dt":"Çok şaşırmış; şok olmuş","e1":"I was flabbergasted when I heard the news.","e1t":"Haberleri duyunca ağzım açık kaldı (şoke oldum).","e2":"She looked flabbergasted.","e2t":"Şaşkınlıktan donakalmış görünüyordu."},{"w":"flaccid","tr":"gevşek / yumuşak / sarkık","te":"Adjective","tt":"Sıfat","de":"(Of part of the body) soft and hanging loosely or limply; or lacking force or effectiveness","dt":"(Vücut için) gevşek, sarkık; veya (etki için) zayıf/cansız","e1":"Flaccid muscles.","e1t":"Gevşek kaslar.","e2":"A flaccid performance.","e2t":"Cansız (sönük) bir performans."},{"w":"flammable","tr":"yanıcı / parlayıcı","te":"Adjective","tt":"Sıfat","de":"Easily set on fire","dt":"Kolayca alev alan","e1":"Flammable liquids.","e1t":"Yanıcı sıvılar.","e2":"Highly flammable material.","e2t":"Çok parlayıcı madde. (Not: 'Inflammable' da aynı anlamdadır)."},{"w":"flay","tr":"(derisini) yüzmek / yerden yere vurmak (eleştiri)","te":"Verb","tt":"Fiil","de":"Peel the skin off (a corpse or carcass); or to criticize severely","dt":"Derisini yüzmek; veya birini acımasızca eleştirmek","e1":"To flay an animal.","e1t":"Bir hayvanın derisini yüzmek.","e2":"He was flayed by the critics.","e2t":"Eleştirmenler tarafından yerden yere vuruldu (haşlandı)."},{"w":"fleck","tr":"benek / leke / çil / noktalamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A very small patch of color or light; or a small particle","dt":"Küçük renk/ışık beneği; veya küçük parçacık","e1":"Flecks of gold in the rock.","e1t":"Kayadaki altın parıltıları (benekleri).","e2":"Her hair was flecked with grey.","e2t":"Saçlarına yer yer kırlar (gri benekler) düşmüştü."},{"w":"fledgling / fledgeling","tr":"yeni yetme / acemi / tüyleri yeni çıkmış kuş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A young bird that has just fledged; or a person or organization that is immature or inexperienced","dt":"Yeni uçmaya başlayan kuş; veya deneyimsiz kişi/kuruluş","e1":"A fledgling company.","e1t":"Yeni kurulmuş (henüz yolun başında) bir şirket.","e2":"Fledgling poets.","e2t":"Yeni yetme (acemi) şairler."},{"w":"fleece","tr":"koyun yünü / polar / dolandırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The woolly coat of a sheep; or to swindle someone","dt":"Koyun postu (yünü); veya (argo) birini soymak/dolandırmak","e1":"A warm fleece jacket.","e1t":"Sıcak bir polar ceket.","e2":"They fleeced the tourists.","e2t":"Turistleri (fazla para alarak) dolandırdılar/soydular."},{"w":"flighty","tr":"değişken / havai / kararsız","te":"Adjective","tt":"Sıfat","de":"Fickle and irresponsible","dt":"Sorumsuz ve değişken ruhlu (havai)","e1":"A flighty young woman.","e1t":"Havai (aklı bir karış havada) genç bir kadın.","e2":"Flighty behavior.","e2t":"Kararsız davranışlar."},{"w":"flit","tr":"(kuş gibi) süzülmek / hızla geçmek / taşınmak","te":"Verb","tt":"Fiil","de":"Move swiftly and lightly, especially from one place to another","dt":"(Kuş/böcek/düşünce gibi) hızla ve hafifçe hareket etmek","e1":"Butterflies flitting from flower to flower.","e1t":"Çiçekten çiçeğe süzülen kelebekler.","e2":"Memories flitted through his mind.","e2t":"Anılar zihninden hızla geçti."},{"w":"floe","tr":"buz kütlesi (denizde yüzen)","te":"Noun","tt":"İsim","de":"A sheet of floating ice","dt":"Denizde yüzen yassı buz tabakası","e1":"An ice floe in the Arctic.","e1t":"Arktik'te yüzen bir buz kütlesi.","e2":"","e2t":""},{"w":"flora","tr":"flora / bitki örtüsü","te":"Noun","tt":"İsim","de":"The plants of a particular region, habitat, or geological period","dt":"Belirli bir bölgeye veya döneme ait bitki varlığı","e1":"The alpine flora.","e1t":"Alp bitki örtüsü.","e2":"Rare flora and fauna.","e2t":"Nadir bitki ve hayvan toplulukları. (Not: 'Fauna'"},{"w":"flotsam","tr":"yüzen enkaz / döküntü / işe yaramaz şeyler","te":"Noun","tt":"İsim","de":"The wreckage of a ship or its cargo found floating on or washed up by the sea","dt":"Denizde yüzen veya kıyıya vuran gemi enkazı/atığı","e1":"Flotsam and jetsam (yüzen ve batmış döküntüler).","e1t":"The flotsam of society.","e2":"Toplumun döküntüleri (başıboş insanlar).","e2t":""},{"w":"flout","tr":"(kuralı) hiçe saymak / çiğnemek / alay etmek","te":"Verb","tt":"Fiil","de":"Openly disregard (a rule, law, or convention)","dt":"Bir kuralı veya yasayı açıkça çiğnemek (yok saymak)","e1":"To flout the law.","e1t":"Yasayı hiçe saymak.","e2":"They flouted the safety regulations.","e2t":"Güvenlik yönetmeliklerini önemsemediler. (Not: 'Flaunt'"},{"w":"fluency","tr":"akıcılık","te":"Noun","tt":"İsim","de":"The quality or condition of being fluent","dt":"Bir dilde veya beceride akıcı olma durumu","e1":"Fluency in English.","e1t":"İngilizcede akıcılık.","e2":"To speak with great fluency.","e2t":"Büyük bir akıcılıkla konuşmak."},{"w":"flummox","tr":"aklını karıştırmak / şaşırtmak","te":"Verb","tt":"Fiil","de":"Perplex (someone) greatly; bewilder","dt":"Birinin kafasını fena halde karıştırmak","e1":"I was completely flummoxed by the question.","e1t":"Soru karşısında tamamen şaşırıp kaldım.","e2":"He looked flummoxed.","e2t":"Kafası karışmış (ne yapacağını şaşırmış) görünüyordu."},{"w":"fluorescence","tr":"floresans / ışılama","te":"Noun","tt":"İsim","de":"The emission of light by a substance that has absorbed light or other electromagnetic radiation","dt":"Bir maddenin aldığı ışığı geri yansıtmasıyla oluşan ışılama","e1":"The fluorescence of certain minerals.","e1t":"Bazı minerallerin floresans özelliği.","e2":"Fluorescent lamp.","e2t":"Floresan lamba."},{"w":"flurry","tr":"telaş / (kar) serpintisi / hareketlilik","te":"Noun/Verb","tt":"İsim/Fiil","de":"A small swirling body of something, especially snow or dust; or a sudden period of commotion","dt":"Küçük (kar) serpintisi; veya ani heyecan/hareketlilik","e1":"A flurry of activity.","e1t":"Bir hareketlilik dalgası (telaş).","e2":"Snow flurries.","e2t":"Kar serpintileri."},{"w":"fluster","tr":"telaşlandırmak / huzursuz etmek / kafa karışıklığı","te":"Verb/Noun","tt":"Fiil/İsim","de":"Make (someone) agitated or confused","dt":"Birini heyecanlandırmak veya kafasını karıştırmak","e1":"Don't let the exam fluster you.","e1t":"Sınavın seni telaşlandırmasına izin verme.","e2":"He was in a bit of a fluster.","e2t":"Biraz telaşlı (huzursuz) bir haldeydi."},{"w":"fluted","tr":"oluklu / yivli","te":"Adjective","tt":"Sıfat","de":"(Of a surface) marked with flutes or grooves","dt":"(Yüzey için) dikine olukları olan","e1":"Fluted columns of a Greek temple.","e1t":"Yunan tapınağının oluklu sütunları.","e2":"Fluted glass.","e2t":"Oluklu cam."},{"w":"foible","tr":"zayıf yön / kusur (küçük ve zararsız)","te":"Noun","tt":"İsim","de":"A minor weakness or eccentricity in someone's character","dt":"Birinin karakterindeki küçük ve zararsız kusur veya tuhaflık","e1":"We all have our little foibles.","e1t":"Hepimizin küçük kusurları vardır.","e2":"To tolerate someone's foibles.","e2t":"Birinin tuhaflıklarına katlanmak."},{"w":"foist","tr":"zorla kabul ettirmek / yutturmak","te":"Verb","tt":"Fiil","de":"Impose an unwelcome or unnecessary person or thing on","dt":"İstenmeyen bir şeyi veya kişiyi birine zorla kabul ettirmek (yüklemek)","e1":"He foisted his responsibilities on his assistant.","e1t":"Sorumluluklarını asistanına yıktı.","e2":"To foist an inferior product on the public.","e2t":"Halka kalitesiz bir ürünü (yutturarak) satmak."},{"w":"foliation","tr":"yapraklanma / tabakalaşma (jeoloji) / sayfalama","te":"Noun","tt":"İsim","de":"The process of forming into leaf","dt":"like layers","e1":"Yapraklara ayrılma veya tabakalar halinde oluşma süreci","e1t":"The foliation of metamorphic rocks.","e2":"Metamorfik kayaçların tabakalaşması.","e2t":"Foliation of a manuscript."},{"w":"foolhardy","tr":"gözü kara / düşüncesizce cesur / cahil cesareti olan","te":"Adjective","tt":"Sıfat","de":"Recklessly bold or rash","dt":"Sonucunu düşünmeden, tehlikeli şekilde cesur olan","e1":"A foolhardy decision.","e1t":"Cahil cesaretiyle alınmış (riskli) bir karar.","e2":"It would be foolhardy to go out in this storm.","e2t":"Bu fırtınada dışarı çıkmak çılgınlık olur."},{"w":"fop","tr":"züppe / giyimine aşırı düşkün erkek","te":"Noun","tt":"İsim","de":"A man who is concerned with his clothes and appearance in an affected and excessive way","dt":"Giyimine ve dış görünüşüne aşırı (ve yapmacık) önem veren erkek","e1":"He was considered a bit of a fop.","e1t":"Biraz züppe biri olarak kabul edilirdi.","e2":"Foppish (adjective).","e2t":"Züppece."},{"w":"foray","tr":"akın / baskın / yeni bir alan denemesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden attack or incursion into enemy territory; or a brief attempt to become involved in a new activity","dt":"Düşman topraklarına ani baskın; veya yeni bir alana yapılan kısa süreli giriş (deneme)","e1":"A military foray.","e1t":"Askeri akın.","e2":"My first foray into politics.","e2t":"Siyasete ilk girişim (denemem)."},{"w":"forbearance","tr":"sabır / hoşgörü / feragat (hukuk)","te":"Noun","tt":"İsim","de":"Patient self","dt":"control; restraint and tolerance","e1":"Sabırlı bir özdenetim; hoşgörü; veya bir haktan geçici vazgeçme","e1t":"To treat someone with forbearance.","e2":"Birine hoşgörüyle (sabırla) davranmak.","e2t":"Debt forbearance."},{"w":"ford","tr":"sığ yer (nehirde) / nehri yürüyerek geçmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shallow place in a river or stream allowing one to walk or drive across","dt":"Bir nehirde yürüyerek veya araçla geçilebilen sığ yer","e1":"They found a ford and crossed the river.","e1t":"Sığ bir yer bulup nehri geçtiler.","e2":"To ford a stream.","e2t":"Çayı yürüyerek geçmek."},{"w":"forebear / forbear","tr":"ata / ecdad","te":"Noun","tt":"İsim","de":"An ancestor","dt":"Atalar, büyükbabalar","e1":"Our forebears struggled for freedom.","e1t":"Atalarımız özgürlük için mücadele etti.","e2":"(Genellikle çoğul kullanılır).","e2t":""},{"w":"foreboding","tr":"kötü his / içine doğma / uğursuzluk","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A feeling that something bad will happen; fearful apprehension","dt":"Kötü bir şey olacağına dair içsel his","e1":"A sense of foreboding.","e1t":"Kötü bir şey olacakmış hissi.","e2":"Foreboding clouds.","e2t":"Uğursuz görünen (karamsar) bulutlar."},{"w":"foreshadow","tr":"habercisi olmak / önceden belirtmek","te":"Verb","tt":"Fiil","de":"Be a warning or indication of (a future event)","dt":"Gelecekteki bir olayı önceden haber vermek veya işaret etmek","e1":"The dark clouds foreshadowed the storm.","e1t":"Karanlık bulutlar fırtınanın habercisiydi.","e2":"The opening scene foreshadows the tragedy at the end.","e2t":"İlk sahne, sondaki trajediyi önceden sezdiriyor."},{"w":"foresight","tr":"öngörü / ileriyi görme / tedbir","te":"Noun","tt":"İsim","de":"The ability to predict or the action of predicting what will happen or be needed in the future","dt":"Gelecekte ne olacağını veya neye ihtiyaç duyulacağını tahmin etme becerisi","e1":"Thanks to his foresight, we were prepared.","e1t":"Onun öngörüsü sayesinde hazırlıklıydık.","e2":"A man of great foresight.","e2t":"İleriyi çok iyi gören adam."},{"w":"forestall","tr":"önlemek / erkenden davranıp engellemek","te":"Verb","tt":"Fiil","de":"Prevent or obstruct (an anticipated event or action) by taking action ahead of time","dt":"Önceden harekete geçerek bir şeyi engellemek veya vaktinden önce davranmak","e1":"To forestall a crisis.","e1t":"Bir krizi önlemek.","e2":"She managed to forestall his question.","e2t":"Soru sormasına fırsat bırakmadan engelledi."},{"w":"forgery","tr":"sahtecilik / sahte belge","te":"Noun","tt":"İsim","de":"The action of forging or producing a copy of a document, signature, banknote, or work of art","dt":"Belge, imza veya sanat eserinin sahtesini yapma eylemi","e1":"He was arrested for forgery.","e1t":"Sahtecilikten tutuklandı.","e2":"A clever forgery.","e2t":"Ustalıkla yapılmış sahte (belge/eser)."},{"w":"forgo / forego","tr":"","te":"den vazgeçmek / feda etmek / mahrum kalmak","tt":"Verb","de":"Fiil","dt":"Omit or decline to take (something pleasant or valuable); go without","e1":"(Zevkli veya değerli bir şeyden) vazgeçmek; feragat etmek","e1t":"To forgo a pay increase.","e2":"Maaş artışından vazgeçmek.","e2t":"He decided to forgo dessert."},{"w":"formality","tr":"formalite / resmiyet / şekilcilik","te":"Noun","tt":"İsim","de":"The rigid observance of conventional forms; or a thing that is done to comply with a rule","dt":"Kurallara sıkı sıkıya bağlılık; veya usulen yapılan işlem","e1":"Legal formalities.","e1t":"Yasal formaliteler.","e2":"The interview was just a formality.","e2t":"Mülakat sadece bir formaliteydi (usul gereğiydi)."},{"w":"forswear","tr":"tövbe etmek / (yeminle) vazgeçmek / yalan yere yemin etmek","te":"Verb","tt":"Fiil","de":"Agree to give up or do without; or to commit perjury","dt":"Bir şeyi yapmayacağına yemin etmek (vazgeçmek); veya yalan yere yemin etmek","e1":"To forswear violence.","e1t":"Şiddete başvurmayacağına yemin etmek.","e2":"He forswore his former beliefs.","e2t":"Eski inançlarından (yeminle) vazgeçti."},{"w":"forte","tr":"güçlü yan / uzmanlık alanı","te":"Noun","tt":"İsim","de":"A thing at which someone excels","dt":"Birinin çok iyi olduğu konu","e1":"Cooking is not my forte.","e1t":"Yemek yapmak benim güçlü yanım değil.","e2":"Public speaking was her forte.","e2t":"Topluluk önünde konuşmak onun uzmanlık alanıydı. (Not: Müzikte 'yüksek sesle' anlamına da gelir)."},{"w":"fortuitous","tr":"tesadüfi / şans eseri","te":"Adjective","tt":"Sıfat","de":"Happening by accident or chance rather than design; fortunate","dt":"Planlı değil, tesadüfen (ve genellikle şanslı bir şekilde) gerçekleşen","e1":"A fortuitous meeting.","e1t":"Şans eseri (tesadüfi) bir karşılaşma.","e2":"The timing was fortuitous.","e2t":"Zamanlama şans eseri çok uygundu."},{"w":"fracas","tr":"kavga / arbede / velvele","te":"Noun","tt":"İsim","de":"A noisy disturbance or quarrel","dt":"Gürültülü kavga veya tartışma","e1":"A minor fracas in the bar.","e1t":"Barda çıkan küçük bir arbede.","e2":"He was involved in a fracas.","e2t":"Bir kavgaya karıştı."},{"w":"frailty","tr":"zayıflık / kırılganlık / kusur","te":"Noun","tt":"İsim","de":"The condition of being weak and delicate; or a fault due to weakness of character","dt":"Zayıf ve narin olma durumu; veya karakter zayıflığından kaynaklanan kusur","e1":"The frailty of old age.","e1t":"Yaşlılığın getirdiği zayıflık.","e2":"Human frailties.","e2t":"İnsani kusurlar (zayıflıklar)."},{"w":"franchise","tr":"bayilik / oy hakkı / imtiyaz","te":"Noun/Verb","tt":"İsim/Fiil","de":"An authorization granted by a government or company to an individual or group enabling them to carry out specified commercial activities","dt":"Ticari faaliyet yürütme izni (bayilik); veya seçme ve seçilme hakkı","e1":"A fast","e1t":"food franchise.","e2":"Bir fast","e2t":"food bayiliği."},{"w":"fresco","tr":"fresk / duvar resmi","te":"Noun","tt":"İsim","de":"A painting done rapidly in watercolor on wet plaster on a wall or ceiling","dt":"Islak sıva üzerine su bazlı boya ile yapılan duvar resmi","e1":"Ancient Roman frescoes.","e1t":"Antik Roma freskleri.","e2":"To paint a fresco.","e2t":"Fresk boyamak."},{"w":"frieze","tr":"friz / süsleme kuşağı / kaba yünlü kumaş","te":"Noun","tt":"İsim","de":"A broad horizontal band of sculpted or painted decoration, especially on a wall near the ceiling","dt":"Duvarın üst kısmında veya sütunların üzerinde yer alan süsleme kuşağı","e1":"A marble frize.","e1t":"Mermer kabartma (friz).","e2":"The Parthenon frieze.","e2t":"Partenon frizi."},{"w":"frigid","tr":"buz gibi / çok soğuk / soğuk (tavır) / cinsel soğukluk","te":"Adjective","tt":"Sıfat","de":"Very cold in temperature; or stiff and formal in manner","dt":"Çok soğuk; veya (tavır için) aşırı resmi ve mesafeli","e1":"The frigid waters of the Arctic.","e1t":"Kuzey Kutbu'nun dondurucu suları.","e2":"A frigid welcome.","e2t":"Çok soğuk bir karşılama."},{"w":"frisk","tr":"(üstünü) aramak / oynaşmak / sıçramak","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a police officer) pass one's hands over (someone) in a search for hidden weapons or drugs","dt":"(Polis için) şüpheliyi elle aramak; veya (hayvan için) neşeyle zıplamak","e1":"The guards frisked all visitors.","e1t":"Gardiyanlar tüm ziyaretçilerin üstünü aradı.","e2":"Lambs frisking in the meadow.","e2t":"Çayırda oynaşan kuzular."},{"w":"fritter","tr":"boşa harcamak (zaman/para) / lokma (kızartma)","te":"Verb/Noun","tt":"Fiil/İsim","de":"Waste time, money, or energy on trifling matters; or a small piece of fried batter","dt":"Zamanı veya parayı ufak tefek şeylere harcayıp tüketmek; veya hamur kızartması","e1":"Don't fritter away your time on social media.","e1t":"Zamanını sosyal medyada çarçur etme.","e2":"Apple fritters.","e2t":"Elmalı hamur kızartması (lokma)."},{"w":"frolic","tr":"oynaşmak / eğlenmek / şenlik","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a person or animal) play and move about cheerfully, excitedly, or energetically","dt":"Neşeyle oynaşmak ve zıplamak","e1":"Children frolicking in the garden.","e1t":"Bahçede oynaşan çocuklar.","e2":"A summer frolic.","e2t":"Yaz eğlencesi."},{"w":"frond","tr":"büyük yaprak (palmiye/eğrelti otu)","te":"Noun","tt":"İsim","de":"The leaf or leaflike part of a palm, fern, or similar plant","dt":"Palmiye veya eğrelti otu gibi bitkilerin büyük, parçalı yaprağı","e1":"Palm fronds.","e1t":"Palmiye yaprakları.","e2":"Fern fronds.","e2t":"Eğrelti otu yaprakları."},{"w":"fumble","tr":"el yordamıyla aramak / beceriksizce tutmak / bocalamak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Use the hands clumsily while doing or handling something","dt":"Bir şeyi yaparken veya tutarken beceriksizce hareket etmek","e1":"To fumble for keys in a bag.","e1t":"Çantada el yordamıyla anahtar aramak.","e2":"He fumbled the ball.","e2t":"Topu elinden kaçırdı (beceriksizce tuttu)."},{"w":"functionary","tr":"memur / görevli / işlevsel","te":"Noun","tt":"İsim","de":"A person who has to perform official functions or duties; an official","dt":"Resmi görevleri yerine getiren kişi (genellikle düşük düzey memur)","e1":"A minor party functionary.","e1t":"Küçük bir parti görevlisi.","e2":"Public functionaries.","e2t":"Kamu görevlileri."},{"w":"fungi / fungus","tr":"mantar / mantarlar","te":"Noun","tt":"İsim","de":"Any of a group of spore","dt":"producing organisms feeding on organic matter","e1":"Organik maddeyle beslenen, sporla çoğalan organizmalar grubu","e1t":"Poisonous fungi.","e2":"Zehirli mantarlar.","e2t":"Fungal infection."},{"w":"furbish","tr":"parlatmak / yenilemek / cilalamak","te":"Verb","tt":"Fiil","de":"Give a fresh look to (something old or shabby); renovate","dt":"Eski bir şeyi yenilemek veya parlatmak","e1":"To furbish old furniture.","e1t":"Eski mobilyaları yenilemek. (Not: Genelde 'Refurbish' olarak kullanılır).","e2":"","e2t":""},{"w":"furor / furore","tr":"velvele / öfke patlaması / büyük heyecan","te":"Noun","tt":"İsim","de":"An outbreak of public anger or excitement","dt":"Halkın gösterdiği büyük tepki (öfke) veya heyecan","e1":"The news caused a great furor.","e1t":"Haberler büyük bir velveleye (tepkiye) neden oldu.","e2":"A furor of applause.","e2t":"Alkış tufanı."},{"w":"fusillade","tr":"yaylım ateşi / bombardıman (soru vb.)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A series of shots fired at the same time or in quick succession","dt":"Aynı anda veya art arda yapılan atışlar (yaylım ateşi)","e1":"A fusillade of bullets.","e1t":"Kurşun yağmuru.","e2":"A fusillade of questions.","e2t":"Soru yağmuru (bombardımanı)."},{"w":"gadfly","tr":"atsineği / can sıkıcı eleştirmen / kışkırtıcı","te":"Noun","tt":"İsim","de":"A fly that bites livestock; or an annoying person who criticizes to provoke others","dt":"Hayvanları ısıran sinek; veya başkalarını harekete geçirmek için sürekli eleştiren can sıkıcı kişi","e1":"He acted as a political gadfly.","e1t":"Siyasi bir kışkırtıcı (eleştiren ses) olarak hareket etti.","e2":"Socrates was called the gadfly of Athens.","e2t":"Sokrates, Atina'nın atsineği olarak adlandırılırdı."},{"w":"gaff","tr":"kanca (balıkçılık) / hata (gaf)","te":"Noun/Verb","tt":"İsim/Fiil","de":"A stick with a hook for landing large fish; or a clumsy social error","dt":"Büyük balıkları çekmek için kanca; veya sosyal bir hata (gaf)","e1":"To land a shark with a gaff.","e1t":"Bir köpekbalığını kancayla karaya çıkarmak.","e2":"To blow the gaff (to reveal a secret).","e2t":"Sırrı ifşa etmek."},{"w":"gaffe","tr":"gaf / sosyal hata","te":"Noun","tt":"İsim","de":"An unintentional act or remark causing embarrassment to its originator","dt":"Utanç verici, istenmeden yapılan sosyal hata","e1":"To commit a serious gaffe.","e1t":"Ciddi bir gaf yapmak.","e2":"A diplomatic gaffe.","e2t":"Diplomatik bir gaf (hata)."},{"w":"gait","tr":"yürüyüş / adım atış tarzı","te":"Noun","tt":"İsim","de":"A person's manner of walking","dt":"Kişinin yürüyüş tarzı","e1":"A steady gait.","e1t":"Kararlı (sarsılmaz) bir yürüyüş.","e2":"An awkward gait.","e2t":"Garip bir yürüyüş tarzı."},{"w":"gall","tr":"safra / küstahlık / sürtünme yarası / kızdırmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Bile; or impudence; or an annoyance","dt":"Safra; veya küstahlık; veya can sıkıcı şey","e1":"He had the gall to ask for more.","e1t":"Daha fazlasını isteyecek kadar küstahlık gösterdi.","e2":"It galls me to have to apologize.","e2t":"Özür dilemek zorunda kalmak beni kızdırıyor (gücüme gidiyor)."},{"w":"galleon","tr":"kalyon (yelkenli gemi)","te":"Noun","tt":"İsim","de":"A large sailing ship with three or more masts used by Spain between the 15th and 18th centuries","dt":"15. ve 18. yüzyıllar arasında kullanılan büyük yelkenli gemi","e1":"A Spanish treasure galleon.","e1t":"İspanyol hazine kalyonu.","e2":"","e2t":""},{"w":"gambit","tr":"hamle / manevra / feda (satrançta)","te":"Noun","tt":"İsim","de":"A device, action, or opening remark, typically one entailing a degree of risk, that is calculated to gain an advantage","dt":"Avantaj elde etmek için yapılan (riskli) hamle veya açılış sözü","e1":"A clever political gambit.","e1t":"Zekice bir siyasi manevra (hamle).","e2":"Opening gambit.","e2t":"Açılış hamlesi."},{"w":"gambol","tr":"zıplamak / oynaşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Run or jump about playfully","dt":"Neşeyle oraya buraya zıplamak (oynaşmak)","e1":"Lambs gambolling in the fields.","e1t":"Tarlada zıplayıp oynayan kuzular.","e2":"(Not: 'Frolic' ile benzerdir).","e2t":""},{"w":"garbled","tr":"anlaşılmaz / bozuk / birbirine karışmış (mesaj vb.)","te":"Adjective","tt":"Sıfat","de":"(Of a message, sound, or transmission) confused and distorted; unclear","dt":"(Mesaj veya ses için) bozulmuş ve anlaşılmaz hale gelmiş","e1":"A garbled message.","e1t":"Birbirine karışmış (anlaşılmayan) bir mesaj.","e2":"The transmission was garbled.","e2t":"Yayın bozuktu."},{"w":"gargoyle","tr":"gargoyl / çörten (heykel şeklinde)","te":"Noun","tt":"İsim","de":"A grotesque carved human or animal face or figure projecting from the gutter of a building","dt":"Binaların çatılarında su akıtmak için kullanılan çirkin suratlı heykeller","e1":"The stone gargoyles of the cathedral.","e1t":"Katedralin taş gargoylları.","e2":"","e2t":""},{"w":"garish","tr":"rüküş / göz alıcı (nahoş şekilde) / cafcaflı","te":"Adjective","tt":"Sıfat","de":"Obtrusively bright and showy; lurid","dt":"Göz tırmalayıcı derecede parlak ve gösterişli","e1":"Garish colors.","e1t":"Cafcaflı (göze batan) renkler.","e2":"A garish neon sign.","e2t":"Rahatsız edici parlaklıkta bir neon tabela."},{"w":"gastronomy","tr":"gastronomi / yemek sanatı","te":"Noun","tt":"İsim","de":"The practice or art of choosing, cooking, and eating good food","dt":"İyi yemek seçme, pişirme ve yeme sanatı","e1":"French gastronomy.","e1t":"Fransız gastronomi sanatı.","e2":"Gastronomic (adjective).","e2t":"Yemekle ilgili."},{"w":"gauche","tr":"kaba / beceriksiz / yordam bilmez (sosyal açıdan)","te":"Adjective","tt":"Sıfat","de":"Lacking ease or grace; unsophisticated and socially awkward","dt":"Sosyal ortamlarda nasıl davranacağını bilmeyen; kaba veya beceriksiz","e1":"A gauche teenager.","e1t":"Sosyal açıdan beceriksiz bir genç.","e2":"Gaucherie (noun).","e2t":"Sosyal beceriksizlik / Kabalık."},{"w":"gauge / gage","tr":"ölçmek / tahmin etmek / ölçü aleti / kalibre","te":"Noun/Verb","tt":"İsim/Fiil","de":"An instrument that measures and gives a visual display of an amount; or to estimate","dt":"Ölçü aleti (sayaç vb.); veya bir şeyi ölçmek/tahmin etmek","e1":"A fuel gauge.","e1t":"Yakıt göstergesi.","e2":"To gauge the reaction of the crowd.","e2t":"Kalabalığın tepkisini ölçmek (tahmin etmek)."},{"w":"gaunt","tr":"bir deri bir kemik / zayıf ve bitkin / çorak","te":"Adjective","tt":"Sıfat","de":"(Of a person) lean and haggard, especially because of suffering, hunger, or age","dt":"(Kişi için) açlık veya hastalıktan dolayı çok zayıf ve bitkin; veya (yer için) kasvetli","e1":"A gaunt face.","e1t":"Bir deri bir kemik kalmış bir yüz.","e2":"The gaunt ruins of the castle.","e2t":"Kalenin kasvetli kalıntıları."},{"w":"gavel","tr":"tokmak (hakim/müzayede)","te":"Noun","tt":"İsim","de":"A small hammer with which an auctioneer, a judge, or the chairman of a meeting hits a surface to call for attention or order","dt":"Dikkat çekmek veya düzeni sağlamak için kullanılan küçük tokmak","e1":"The judge rapped his gavel for order.","e1t":"Yargıç düzeni sağlamak için tokmağını vurdu.","e2":"","e2t":""},{"w":"generative","tr":"üretken / yaratıcı","te":"Adjective","tt":"Sıfat","de":"Relating to or capable of production or reproduction","dt":"Üretme veya çoğaltma yeteneği olan","e1":"Generative artificial intelligence (GenAI).","e1t":"Üretken yapay zeka.","e2":"The generative power of nature.","e2t":"Doğanın üretici gücü."},{"w":"genesis","tr":"oluşum / doğuş / başlangıç","te":"Noun","tt":"İsim","de":"The origin or mode of formation of something","dt":"Bir şeyin kökeni veya oluşum biçimi","e1":"The genesis of a new idea.","e1t":"Yeni bir fikrin doğuşu.","e2":"The book tracks the genesis of the conflict.","e2t":"Kitap, çatışmanın başlangıcını izliyor."},{"w":"genitals / genitalia","tr":"cinsel organlar","te":"Noun","tt":"İsim (Plural)","de":"The reproductive organs, especially those that are external","dt":"Özellikle dışarıda bulunan üreme organları","e1":"External genitalia.","e1t":"Dış cinsel organlar.","e2":"","e2t":""},{"w":"gentility","tr":"soyluluk / kibarlık / iyi aile terbiyesi","te":"Noun","tt":"İsim","de":"Social superiority as demonstrated by polite and refined manners","dt":"Nazik ve rafine tavırlarla gösterilen sosyal üstünlük veya iyi terbiye","e1":"A man of gentility.","e1t":"Kibar ve terbiyeli (asil ruhlu) bir adam.","e2":"To maintain an air of gentility.","e2t":"Soyluluk havasını korumak."},{"w":"genuflect","tr":"diz çökmek (saygıdan) / dalkavukluk yapmak","te":"Verb","tt":"Fiil","de":"Lower one's body briefly by bending one knee to the ground, typically in worship or as a sign of respect","dt":"Genellikle ibadet veya saygı amacıyla tek dizi üzerine çökmek","e1":"To genuflect before the altar.","e1t":"Sunak önünde diz çökmek.","e2":"They were expected to genuflect to the dictator.","e2t":"Diktatörün önünde (saygıyla/dalkavukça) eğilmeleri bekleniyordu."},{"w":"germinal","tr":"başlangıç aşamasındaki / tohum halindeki","te":"Adjective","tt":"Sıfat","de":"Relating to or of the nature of a germ or germ cell; in the earliest stage of development","dt":"Bir tohum veya hücreyle ilgili; gelişimin en erken evresindeki","e1":"A germinal idea.","e1t":"Tohum halindeki (gelişmeye müsait) fikir.","e2":"Germinal layers (biology).","e2t":"Embriyonik tabakalar."},{"w":"gerontology","tr":"gerontoloji / yaşlılık bilimi","te":"Noun","tt":"İsim","de":"The scientific study of old age, the process of aging, and the particular problems of old people","dt":"Yaşlılığı ve yaşlanma sürecini inceleyen bilim dalı","e1":"Social gerontology.","e1t":"Sosyal gerontoloji.","e2":"Gerontologist (noun).","e2t":"Yaşlılık bilimci."},{"w":"gerrymander","tr":"(seçim bölgelerini) hileyle düzenlemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Manipulate the boundaries of an electoral constituency so as to favor one party or class","dt":"Bir partinin lehine olacak şekilde seçim bölgelerinin sınırlarını kurnazca değiştirmek","e1":"To gerrymander the voting districts.","e1t":"Seçim bölgelerini (haksız avantaj için) yeniden düzenlemek.","e2":"Gerrymandering (noun).","e2t":"Seçim bölgesi manipülasyonu."},{"w":"gestate","tr":"(cenini) taşımak / hamile olmak / (fikri) olgunlaştırmak","te":"Verb","tt":"Fiil","de":"Carry a fetus in the womb from conception to birth; or to develop over a long period","dt":"Hamilelik süresince cenini taşımak; veya bir fikri uzun sürede olgunlaştırmak","e1":"The project has been gestating for years.","e1t":"Proje yıllardır olgunlaşıyor (hazırlanıyor).","e2":"Gestation period.","e2t":"Gebelik süresi."},{"w":"gesticulation","tr":"el kol hareketi / jest","te":"Noun","tt":"İsim","de":"A gesture, especially a dramatic one, used instead of speaking or to emphasize one's words","dt":"Konuşmak yerine veya konuşmayı vurgulamak için yapılan (genellikle abartılı) el kol hareketleri","e1":"He accompanied his speech with wild gesticulations.","e1t":"Konuşmasına çılgınca el kol hareketleri eşlik etti.","e2":"Gesticulate (verb).","e2t":"El kol hareketi yapmak."},{"w":"gibberish","tr":"anlaşılmaz söz / saçmalık / zırva","te":"Noun","tt":"İsim","de":"Unintelligible or meaningless speech or writing; nonsense","dt":"Anlamsız veya kafa karıştırıcı konuşma/yazı","e1":"Stop talking gibberish!","e1t":"Saçmalamayı (anlamsız konuşmayı) bırak!","e2":"Computer gibberish.","e2t":"Bilgisayarın çıkardığı anlamsız karakterler."},{"w":"gibe / jibe","tr":"alay etmek / aşağılayıcı söz / dalga geçmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"An insulting or mocking remark; a taunt","dt":"Aşağılayıcı veya alaycı söz; sataşma","e1":"He ignored their gibes.","e1t":"Onların alaylarını görmezden geldi.","e2":"To gibe at someone's failure.","e2t":"Birinin başarısızlığıyla dalga geçmek."},{"w":"gild","tr":"yaldızlamak / altınla kaplamak / süslemek","te":"Verb","tt":"Fiil","de":"Cover thinly with gold; or to give a specious or false brilliance to","dt":"Üzerini ince bir altın tabakasıyla kaplamak; veya bir şeyi olduğundan parlak göstermek","e1":"To gild the edges of a book.","e1t":"Bir kitabın kenarlarını yaldızlamak.","e2":"\"To gild the lily\" (idiom: zaten güzel olan bir şeyi gereksiz süslemek).","e2t":""},{"w":"girth","tr":"çevre (bel/gövde) / kolon (eyer)","te":"Noun","tt":"İsim","de":"The measurement around the middle of something, especially a person's waist; or a band around a horse","dt":"Bir şeyin orta kısmının çevre ölçüsü (bel çevresi); veya atın karnına bağlanan kolon","e1":"A man of enormous girth.","e1t":"Bel çevresi çok geniş (göbekli) bir adam.","e2":"To tighten the girth.","e2t":"(Atın) kolonunu sıkmak."},{"w":"glacial","tr":"buzul / çok soğuk / çok yavaş","te":"Adjective","tt":"Sıfat","de":"Relating to or denoting glaciers or ice sheets; or icy cold; or extremely slow","dt":"Buzullarla ilgili; veya buz gibi soğuk; veya (ilerleme için) çok yavaş","e1":"Glacial period (ice age).","e1t":"Buzul çağı.","e2":"Progress has been glacial.","e2t":"İlerleme buzul hızıyla (çok yavaş) oldu."},{"w":"glaring","tr":"göz alıcı / bariz / apaçık (olumsuz)","te":"Adjective","tt":"Sıfat","de":"(Of a light) giving out or reflecting a strong or dazzling light; or (of something bad) highly obvious","dt":"(Işık için) göz kamaştırıcı; veya (kötü bir şey için) apaçık, fahiş","e1":"A glaring error.","e1t":"Apaçık (bariz) bir hata.","e2":"The glaring sun.","e2t":"Göz alan güneş."},{"w":"glaze","tr":"sır / cila / cam takmak / donuklaşmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A vitreous substance fused on to the surface of pottery; or to become glassy","dt":"Seramik yüzeyindeki camsı tabaka (sır); veya (göz için) donuklaşmak/cam gibi bakmak","e1":"To glaze a window.","e1t":"Bir pencereye cam takmak.","e2":"His eyes glazed over with boredom.","e2t":"Can sıkıntısından gözlerine cam (donukluk) geldi."},{"w":"gloss","tr":"parlaklık / cila / şerh (not) / örtbas etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shiny surface; or an explanation or interpretation; or to try to conceal","dt":"Parlak yüzey; veya (metne düşülen) açıklayıcı not; veya (hata vb.) örtbas etmek","e1":"Lip gloss.","e1t":"Dudak parlatıcısı.","e2":"To gloss over a mistake.","e2t":"Bir hatayı geçiştirmek (örtbas etmek)."},{"w":"glossary","tr":"sözlükçe / terimler sözlüğü","te":"Noun","tt":"İsim","de":"An alphabetical list of terms or words found in or relating to a specific subject with explanations","dt":"Belirli bir konuyla ilgili terimlerin açıklamalı ve alfabetik listesi","e1":"A glossary of technical terms.","e1t":"Teknik terimler sözlüğü.","e2":"Look it up in the glossary at the back of the book.","e2t":"Kitabın sonundaki sözlükçeden bak."},{"w":"glower","tr":"öfkeyle bakmak / ters ters bakmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Have an angry or sullen look on one's face; scowl","dt":"Öfkeli veya somurtkan bir ifadeyle (kaşlarını çatarak) bakmak","e1":"He glowered at me throughout the meeting.","e1t":"Toplantı boyunca bana öfkeyle (ters ters) baktı.","e2":"A dark glower.","e2t":"Karanlık, öfkeli bir bakış."},{"w":"glut","tr":"fazlalık / doyurmak / piyasayı mal ile doldurmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"An excessively abundant supply of something; or to supply or fill to excess","dt":"Bir şeyin aşırı miktarda arzı; veya (piyasayı/kendini) aşırı doldurmak","e1":"A glut of oil on the market.","e1t":"Piyasada petrol fazlalığı.","e2":"To glut oneself with food.","e2t":"Tıka basa (doyana kadar) yemek."},{"w":"glutinous","tr":"yapışkan / ağdalı","te":"Adjective","tt":"Sıfat","de":"Like glue in texture; sticky","dt":"Doku olarak tutkal gibi; yapış yapış","e1":"Glutinous rice.","e1t":"Yapışkan pirinç.","e2":"A glutinous liquid.","e2t":"Ağdalı (yapışkan) bir sıvı."},{"w":"glutton","tr":"obur / doymak bilmez kimse","te":"Noun","tt":"İsim","de":"An excessively greedy eater; or a person with a great capacity for something","dt":"Aşırı yemek yiyen kişi; veya bir şeye doymak bilmeyen","e1":"He is a glutton for work (hard worker).","e1t":"O tam bir iş koliktir (işe doymaz).","e2":"Gluttony (noun).","e2t":"Oburluk / Boğazına düşkünlük."},{"w":"gnarled","tr":"budaklı / yamru yumru / pürüzlü","te":"Adjective","tt":"Sıfat","de":"Knotted, rough, and twisted, especially with age","dt":"(Ağaç veya el için) yaşla birlikte düğümlenmiş, pürüzlü ve eğrilmiş","e1":"The gnarled branches of an old oak.","e1t":"Yaşlı bir meşenin budaklı dalları.","e2":"Gnarled hands.","e2t":"(Yaşlılıktan) boğum boğum olmuş eller."},{"w":"gnash","tr":"(diş) gıcırdatmak","te":"Verb","tt":"Fiil","de":"To grind one's teeth together, typically in anger","dt":"Dişlerini birbirine sürtmek, genellikle öfkeden","e1":"He gnashed his teeth in frustration.","e1t":"Hayal kırıklığıyla dişlerini gıcırdattı.","e2":"Gnash one's teeth.","e2t":"Diş gıcırdatmak."},{"w":"gnome","tr":"yer cücesi / özlü söz / cin (finans)","te":"Noun","tt":"İsim","de":"A legendary dwarfish creature supposed to guard the earth's treasures; or a pithy saying","dt":"Yerin altındaki hazineleri koruduğuna inanılan efsanevi cüce; veya özlü söz","e1":"Garden gnome.","e1t":"Bahçe cücesi.","e2":"The gnomes of Zurich (influential bankers).","e2t":"Zürih'in (güçlü) bankerleri."},{"w":"goad","tr":"dürtmek / kışkırtmak / üvendire","te":"Noun/Verb","tt":"İsim/Fiil","de":"A spiked stick used for driving cattle; or to provoke or annoy someone into action","dt":"Hayvan dürtmek için kullanılan ucu sivri değnek; veya birini bir şey yapması için kışkırtmak","e1":"He was goaded into losing his temper.","e1t":"Öfkesini kaybetmesi için kışkırtıldı.","e2":"To goad someone into action.","e2t":"Birini harekete geçmesi için dürtmek."},{"w":"gouge","tr":"oymak / (gözünü) çıkarmak / fahiş fiyat istemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Make a rough hole or indentation in; or an overcharge","dt":"Kaba bir delik veya çukur açmak (oymak); veya fahiş fiyat uygulamak","e1":"To gouge out an eye.","e1t":"Bir gözü oymak (çıkarmak).","e2":"Price gouging (during a crisis).","e2t":"(Kriz anında) fahiş fiyat uygulama."},{"w":"gourmet","tr":"gurme / yemek eksperi","te":"Noun","tt":"İsim","de":"A connoisseur of good food; a person with a discerning palate","dt":"İyi yemekten anlayan, seçici damak tadı olan uzman","e1":"A gourmet restaurant.","e1t":"Gurme restoranı.","e2":"Gourmet coffee.","e2t":"Kaliteli (seçkin) kahve."},{"w":"graduated","tr":"kademeli / dereceli / mezun","te":"Adjective","tt":"Sıfat","de":"Arranged in a series or according to a scale","dt":"Bir ölçeğe veya seriye göre düzenlenmiş (kademeli)","e1":"A graduated income tax.","e1t":"Kademeli gelir vergisi.","e2":"A graduated cylinder (measuring cylinder).","e2t":"Dereceli silindir (mezür)."},{"w":"granary","tr":"tahıl ambarı / zahire deposu","te":"Noun","tt":"İsim","de":"A storehouse for threshed grain","dt":"Harmanlanmış tahılın saklandığı bina/depo","e1":"The Ukraine is often called the granary of Europe.","e1t":"Ukrayna sık sık Avrupa'nın tahıl ambarı olarak adlandırılır.","e2":"","e2t":""},{"w":"granulate","tr":"tanecikli hale getirmek / pürüzlendirmek","te":"Verb","tt":"Fiil","de":"Form into grains or particles","dt":"Tanecik veya granül haline getirmek","e1":"Granulated sugar.","e1t":"Toz şeker (granül şeker).","e2":"The surface was granulated to prevent slipping.","e2t":"Kaymayı önlemek için yüzey pürüzlendirildi (tanecikli yapıldı)."},{"w":"graphite","tr":"grafit / kurşun kalem ucu","te":"Noun","tt":"İsim","de":"A grey crystalline form of carbon that occurs as a mineral","dt":"Karbonun bir formu olan ve kurşun kalem ucu olarak kullanılan mineral","e1":"Graphite is used as a lubricant.","e1t":"Grafit yağlayıcı olarak kullanılır.","e2":"The lead in a pencil is actually graphite.","e2t":"Kalem ucu aslında grafittir."},{"w":"grate","tr":"rendelemek / gıcırdatmak / rahatsız etmek / ızgara","te":"Verb/Noun","tt":"Fiil/İsim","de":"Reduce to small shreds by rubbing it on a grater; or to make a harsh noise","dt":"Rendelemek; veya (ses için) gıcırdatmak (tırmalamak); veya ızgara/parmaklık","e1":"To grate cheese.","e1t":"Peynir rendelemek.","e2":"A grating voice.","e2t":"Tırmalayıcı (rahatsız edici) bir ses."},{"w":"gratis","tr":"bedava / ücretsiz","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Without charge; free","dt":"Ücretsiz olarak","e1":"The food was provided gratis.","e1t":"Yemek bedava sağlandı.","e2":"A gratis service.","e2t":"Ücretsiz bir hizmet."},{"w":"gratuity","tr":"bahşiş / ikramiye","te":"Noun","tt":"İsim","de":"A tip given to a waiter, taxi driver, etc.; or a sum of money paid to an employee at the end of their period of employment","dt":"Bahşiş; veya (emeklilik vb. sonunda verilen) ikramiye","e1":"Service charge is included; no gratuity is necessary.","e1t":"Servis ücreti dahildir; bahşişe gerek yok.","e2":"Retirement gratuity.","e2t":"Emeklilik ikramiyesi."},{"w":"grime","tr":"kir / pas / is / pislik","te":"Noun/Verb","tt":"İsim/Fiil","de":"Dirt ingrained on the surface of something","dt":"Yüzeye işlemiş is veya kir","e1":"Windows covered in grime.","e1t":"İs/kir içinde kalmış pencereler.","e2":"Grimy (adjective).","e2t":"Kirli / Pis."},{"w":"gripe","tr":"şikayet etmek / sızlanmak / karın ağrısı","te":"Verb/Noun","tt":"Fiil/İsim","de":"Complain about something in a persistent, irritating way","dt":"Sürekli ve sinir bozucu şekilde şikayet etmek; sızlanmak","e1":"Stop griping about the weather!","e1t":"Hava hakkında sızlanmayı bırak!","e2":"My main gripe is the low pay.","e2t":"Asıl şikayetim (derdim) düşük maaş."},{"w":"grisly","tr":"korkunç / dehşet verici / vahşet dolu","te":"Adjective","tt":"Sıfat","de":"Causing horror or disgust","dt":"Dehşet veya tiksinti uyandıran","e1":"A grisly murder scene.","e1t":"Korkunç (vahşet dolu) bir cinayet mahalli.","e2":"The grisly details of the accident.","e2t":"Kazanın tüyler ürpertici detayları. (Not: 'Grizzly'"},{"w":"grit","tr":"kum tanesi / çakıl / metanet / dişini sıkmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"Small loose particles of stone or sand; or courage and resolve","dt":"Kum/taş parçacığı; veya (mecazi) cesaret ve dayanıklılık","e1":"To have a lot of grit.","e1t":"Çok metanetli (dayanıklı) olmak.","e2":"To grit your teeth.","e2t":"Dişlerini sıkmak (zorluğa dayanmak)."},{"w":"grizzled","tr":"kırlaşmış (saç/sakal) / bozlaşmış","te":"Adjective","tt":"Sıfat","de":"Having or streaked with grey hair","dt":"Grileşmiş veya saçına ak düşmüş","e1":"A grizzled old veteran.","e1t":"Saçı sakalı kırlaşmış eski bir asker.","e2":"A grizzled beard.","e2t":"Kır sakal."},{"w":"groom","tr":"damat / seyis / tımar etmek / hazırlamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A man on his wedding day; or to brush and clean an animal; or to prepare someone for a role","dt":"Damat; veya (hayvanı) temizlemek; veya birini bir göreve hazırlamak (yetiştirmek)","e1":"The bride and the groom.","e1t":"Gelin ve damat.","e2":"To groom a horse.","e2t":"Atı tımar etmek."},{"w":"groove","tr":"oluk / yiv / kanal / rutin","te":"Noun/Verb","tt":"İsim/Fiil","de":"A long, narrow cut or line in a surface; or an established routine","dt":"Yüzeydeki uzun, dar kanal (yiv); veya (mecazi) alışılmış düzen/rutin","e1":"The grooves on a record.","e1t":"Plaktaki kanallar.","e2":"To get back into the groove.","e2t":"Eski rutinine (formuna) geri dönmek."},{"w":"grotto","tr":"mağara (küçük ve süslü) / suni mağara","te":"Noun","tt":"İsim","de":"A small picturesque cave, especially an artificial one in a garden","dt":"Küçük, güzel manzaralı mağara (genellikle bahçelerdeki yapay olanlar)","e1":"A shell","e1t":"lined grotto.","e2":"Deniz kabuklarıyla süslü mağara.","e2t":"Santa's grotto."},{"w":"grouch","tr":"huysuz kimse / sızlanmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A habitually complaining or irritable person","dt":"Sürekli şikayet eden, huysuz kişi","e1":"He is such an old grouch.","e1t":"Tam bir huysuz ihtiyardır.","e2":"Grouchy (adjective).","e2t":"Huysuz / Aksi."},{"w":"grouse","tr":"keklik (orman tavuğu) / sızlanmak / şikayet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A medium to large game bird; or to complain pettily","dt":"Orman tavuğu; veya ufak tefek şeyler için sızlanmak","e1":"To go grouse shooting.","e1t":"Keklik avına gitmek.","e2":"She's always grousing about the service.","e2t":"Sürekli servis hakkında sızlanıp duruyor."},{"w":"grovel","tr":"yaltaklanmak / ayaklarına kapanmak / yerde sürünmek","te":"Verb","tt":"Fiil","de":"Lie or move abjectly on the ground with one's face downwards; or to act obsequiously","dt":"Yüzüstü yere kapanmak; veya (birinden bir şey istemek için) dalkavukluk etmek","e1":"To grovel before a king.","e1t":"Bir kralın ayaklarına kapanmak.","e2":"I won't grovel to him for a job.","e2t":"Bir iş için ona yaltaklanmayacağım."},{"w":"gruel","tr":"lapa (yulaf) / yorucu","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A thin liquid food of oatmeal boiled in water or milk","dt":"Su veya sütle pişirilmiş sulu yulaf lapası","e1":"A bowl of gruel.","e1t":"Bir kase lapa.","e2":"Grueling / Gruelling (adjective: çok yorucu/yıpratıcı).","e2t":""},{"w":"guffaw","tr":"kahkaha atmak / kaba kahkaha","te":"Noun/Verb","tt":"İsim/Fiil","de":"A loud and boisterous laugh","dt":"Yüksek sesli ve kaba kahkaha","e1":"He let out a loud guffaw.","e1t":"Patlattı kahkahayı.","e2":"To guffaw at a joke.","e2t":"Bir şakaya kaba kaba gülmek."},{"w":"guileless","tr":"saf / dürüst / hilesiz","te":"Adjective","tt":"Sıfat","de":"Devoid of guile; innocent and without deception","dt":"Sinsilikten arınmış; masum ve dürüst","e1":"A guileless young man.","e1t":"Saf (temiz kalpli) bir genç adam.","e2":"She gave a guileless answer.","e2t":"Çok dürüstçe (hile karıştırmadan) bir cevap verdi."},{"w":"guise","tr":"kılık / kisve / görünüm","te":"Noun","tt":"İsim","de":"An external form, appearance, or manner, typically concealing the true nature","dt":"Genellikle gerçek durumu gizleyen dış görünüş","e1":"In the guise of a friend.","e1t":"Arkadaş kılığında (kisvesi altında).","e2":"Under the guise of a tourist.","e2t":"Turist görünümü altında."},{"w":"gull","tr":"martı / kandırmak / enayi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A seabird; or to fool or deceive someone","dt":"Martı; veya birini kandırmak/aldatmak","e1":"A flock of gulls.","e1t":"Martı sürüsü.","e2":"He was gulled into thinking he'd won.","e2t":"Kazandığını sanması için kandırıldı."},{"w":"gummy","tr":"yapışkan / diş etine ait","te":"Adjective","tt":"Sıfat","de":"Viscous; sticky; or relating to the gums","dt":"Yapış yapış; veya diş etleriyle ilgili","e1":"A gummy substance.","e1t":"Yapışkan bir madde.","e2":"A gummy smile (showing a lot of gums).","e2t":"Diş etlerinin çok göründüğü bir gülüş."},{"w":"gust","tr":"ani rüzgar / hamle / patlak verme","te":"Noun/Verb","tt":"İsim/Fiil","de":"A sudden strong rush of wind","dt":"Ani ve güçlü rüzgar esintisi","e1":"Gusts of up to 60 mph.","e1t":"Saatte 60 mil hıza ulaşan rüzgar hamleleri.","e2":"A gust of laughter.","e2t":"Bir kahkaha patlaması."},{"w":"gustatory","tr":"tat alma ile ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the sense of taste","dt":"Tat alma duyusuyla ilgili","e1":"Gustatory pleasure.","e1t":"Tat alma zevki.","e2":"Gustatory perception.","e2t":"Tat algısı."},{"w":"gutter","tr":"oluk / kanal / kenar mahalle / (mum) eriyip akmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A shallow trough fixed beneath the edge of a roof for carrying off rainwater; or the lowest part of society","dt":"Çatı kenarındaki yağmur oluğu; veya toplumun en alt (pis) tabakası","e1":"Rainwater poured from the gutter.","e1t":"Yağmur suyu oluktan boşaldı.","e2":"The language of the gutter.","e2t":"Sokak (kenar mahalle) ağzı."},{"w":"guttural","tr":"gırtlaktan çıkan / hırıltılı","te":"Adjective","tt":"Sıfat","de":"(Of a speech sound) produced in the throat; harsh","dt":"sounding","e1":"Boğazdan gelen; hırıltılı ses","e1t":"A guttural voice.","e2":"Gırtlaktan gelen (kaba) bir ses.","e2t":"The guttural sounds of the language."},{"w":"gymnastics","tr":"jimnastik","te":"Noun","tt":"İsim","de":"Exercises developing or displaying physical agility and coordination","dt":"Fiziksel çeviklik ve koordinasyonu geliştiren egzersizler","e1":"To do gymnastics.","e1t":"Jimnastik yapmak.","e2":"Mental gymnastics (complex thinking).","e2t":"Zihin jimnastiği."},{"w":"gyrate","tr":"dönmek / ekseni etrafında dönmek","te":"Verb","tt":"Fiil","de":"Move or cause to move in a circle or spiral, especially quickly","dt":"Dairesel veya spiral bir şekilde (hızla) dönmek","e1":"The dancers began to gyrate on the floor.","e1t":"Dansçılar pistte dönmeye (kıvırmaya) başladılar.","e2":"Gyration (noun).","e2t":"Dönme / Devir."},{"w":"gyroscope","tr":"jiroskop","te":"Noun","tt":"İsim","de":"A device consisting of a wheel or disk mounted so that it can spin rapidly about an axis which is itself free to alter in direction","dt":"Yönü değişebilen bir eksen üzerinde hızla dönen çarktan oluşan, denge sağlayan düzenek","e1":"Gyroscopes are used in navigation.","e1t":"Jiroskoplar navigasyonda (yön bulmada) kullanılır.","e2":"The gyroscope keeps the ship stable.","e2t":"Jiroskop geminin dengesini korur."},{"w":"habitual","tr":"alışılmış / kronik / sürekli","te":"Adjective","tt":"Sıfat","de":"Done or doing constantly or as a habit","dt":"Bir alışkanlık olarak sürekli yapılan","e1":"Habitual lateness.","e1t":"Kronik geç kalma huyu.","e2":"A habitual liar.","e2t":"İflah olmaz (sürekli yalan söyleyen) yalancı."},{"w":"habituate","tr":"alıştırmak / huy edindirmek","te":"Verb","tt":"Fiil","de":"Make or become accustomed or used to something","dt":"Bir şeye alıştırmak veya bir durumu alışkanlık haline getirmek","e1":"He had habituated himself to working late.","e1t":"Kendini geç saatlere kadar çalışmaya alıştırmıştı.","e2":"To habituate a child to good manners.","e2t":"Bir çocuğa iyi görgü kurallarını ahlak edindirmek."},{"w":"hackneyed","tr":"basmakalıp / klişe / bayat","te":"Adjective","tt":"Sıfat","de":"(Of a phrase or idea) lacking significance through having been overused; unoriginal","dt":"Çok fazla kullanıldığı için orijinalliğini ve önemini yitirmiş (klişe)","e1":"A hackneyed plot.","e1t":"Basmakalıp (bayat) bir olay örgüsü.","e2":"Hackneyed expressions like \"at the end of the day\".","e2t":"\"Günün sonunda\" gibi klişe ifadeler."},{"w":"haggle","tr":"pazarlık etmek / sıkı pazarlık yapmak","te":"Verb","tt":"Fiil","de":"Dispute or bargain persistently, especially over the cost of something","dt":"Özellikle bir şeyin fiyatı üzerinde ısrarla tartışmak (pazarlık yapmak)","e1":"To haggle over the price of a carpet.","e1t":"Bir halının fiyatı üzerinde pazarlık yapmak.","e2":"She spent twenty minutes haggling with the vendor.","e2t":"Satıcıyla pazarlık yaparak yirmi dakika harcadı."},{"w":"halcyon","tr":"huzurlu / sakin / görkemli (geçmiş)","te":"Adjective","tt":"Sıfat","de":"Denoting a period of time in the past that was idyllically happy and peaceful","dt":"Geçmişteki çok huzurlu, mutlu ve sakin (altın çağ) dönem","e1":"The halcyon days of my youth.","e1t":"Gençliğimin o huzurlu ve mutlu günleri.","e2":"A halcyon atmosphere.","e2t":"Sakin ve huzurlu bir ortam."},{"w":"hale","tr":"sağlıklı / zinde / dinç (yaşlılar için)","te":"Adjective","tt":"Sıfat","de":"(Of a person, especially an elderly one) strong and healthy","dt":"(Özellikle yaşlılar için) güçlü ve sağlıklı","e1":"Hale and hearty.","e1t":"Turp gibi (sağlıklı ve dinç).","e2":"He is still hale at eighty.","e2t":"Seksen yaşında olmasına rağmen hala çok dinç."},{"w":"hallowed","tr":"kutsal / kutsanmış","te":"Adjective","tt":"Sıfat","de":"Made holy; consecrated; or greatly revered and honored","dt":"Kutsal sayılan; çok saygı duyulan ve onurlandırılan","e1":"Hallowed ground.","e1t":"Kutsal topraklar.","e2":"The hallowed halls of the university.","e2t":"Üniversitenin o çok saygın (kutsal) koridorları."},{"w":"halting","tr":"duraksayan / aksayan / tereddütlü","te":"Adjective","tt":"Sıfat","de":"Slow and hesitant, especially through lack of confidence; faltering","dt":"Özellikle güven eksikliğinden dolayı yavaş ve duraksayan","e1":"To speak in halting English.","e1t":"Duraksayarak (aksayan bir) İngilizce ile konuşmak.","e2":"A halting progress.","e2t":"Aksak bir ilerleme."},{"w":"handbill","tr":"el ilanı / broşür","te":"Noun","tt":"İsim","de":"A small printed advertisement or notice that is given out by hand","dt":"El ile dağıtılan küçük basılı ilan veya duyuru","e1":"To distribute handbills in the street.","e1t":"Sokakta el ilanı dağıtmak.","e2":"(Not: Flyer daha yaygındır).","e2t":""},{"w":"harangue","tr":"uzun ve ateşli nutuk / kafa ütülemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A lengthy and aggressive speech; or to lecture someone at length in an aggressive way","dt":"Uzun, saldırgan ve ateşli konuşma (nutuk)","e1":"He delivered a long harangue against the government.","e1t":"Hükümete karşı uzun ve sert bir nutuk çekti.","e2":"To harangue someone about their mistakes.","e2t":"Birini hataları hakkında uzun uzun haşlamak (kafasını ütülemek)."},{"w":"harbinger","tr":"haberci / müjdeci / alamet","te":"Noun","tt":"İsim","de":"A person or thing that announces or signals the approach of another","dt":"Bir şeyin yaklaştığını haber veren kişi veya olay","e1":"The swallow is a harbinger of spring.","e1t":"Kırlangıç baharın habercisidir.","e2":"A harbinger of doom.","e2t":"Felaket alameti."},{"w":"harry","tr":"taciz etmek / akın etmek / canından bezdirmek","te":"Verb","tt":"Fiil","de":"Persistently carry out attacks on; or to persistently ask someone to do something","dt":"Sürekli saldırılar düzenlemek; veya birini sürekli rahatsız etmek","e1":"The army was harried by guerrilla attacks.","e1t":"Ordu gerilla saldırılarıyla yıpratıldı.","e2":"To harry someone with questions.","e2t":"Birini sorularla bunaltmak (taciz etmek)."},{"w":"haughtiness","tr":"kibir / tepeden bakma / gurur","te":"Noun","tt":"İsim","de":"The appearance or quality of being arrogantly superior and disdainful","dt":"Kibirli, üstünlük taslayan ve küçümseyen tavır","e1":"Her haughtiness made her unpopular.","e1t":"Kibri onu sevilmeyen biri yaptı.","e2":"Haughty (adjective).","e2t":"Kibirli / Mağrur."},{"w":"hazardous","tr":"tehlikeli / riskli","te":"Adjective","tt":"Sıfat","de":"Risky; dangerous","dt":"Tehlikeli veya riskli","e1":"Hazardous waste.","e1t":"Tehlikeli atık.","e2":"A hazardous journey.","e2t":"Riskli bir yolculuk."},{"w":"hazy","tr":"puslu / dumanlı / belirsiz / kafası karışık","te":"Adjective","tt":"Sıfat","de":"Covered by a haze; or vague or indistinct","dt":"Puslu (sisli); veya tam net olmayan (belirsiz)","e1":"A hazy afternoon.","e1t":"Puslu bir öğleden sonra.","e2":"I have a hazy memory of that day.","e2t":"O güne dair hayal meyal (belirsiz) bir anım var."},{"w":"headstrong","tr":"dikbaşlı / inatçı / burnunun dikine giden","te":"Adjective","tt":"Sıfat","de":"Self","dt":"willed and obstinate","e1":"İnatçı ve sadece kendi bildiğini okuyan","e1t":"A headstrong teenager.","e2":"Dikbaşlı bir genç.","e2t":"He was too headstrong to listen to advice."},{"w":"healthful","tr":"sağlıklı / sağlığa yararlı","te":"Adjective","tt":"Sıfat","de":"Conducive to good health; wholesome","dt":"Sağlığa iyi gelen; yararlı","e1":"Healthful food.","e1t":"Sağlıklı gıda.","e2":"A healthful climate.","e2t":"Sağlıklı bir iklim. (Not: Healthy hem \"sağlıklı olan\" hem de \"sağlığa yararlı\" anlamında daha yaygın kullanılır)."},{"w":"heckle","tr":"sözünü kesmek / (konuşmacıya) laf atmak","te":"Verb","tt":"Fiil","de":"Interrupt (a public speaker) with derisive or aggressive comments","dt":"Bir konuşmacının sözünü alaycı veya saldırgan yorumlarla kesmek","e1":"He was heckled throughout his speech.","e1t":"Konuşması boyunca kendisine laf atıldı (sözü kesildi).","e2":"Heckler (noun).","e2t":"Laf atan/rahatsız eden kişi."},{"w":"hedonist","tr":"hedonist / hazcı / zevk düşkünü","te":"Noun","tt":"İsim","de":"A person who believes that the pursuit of pleasure is the most important thing in life","dt":"Hayatın en önemli amacının haz almak olduğuna inanan kişi","e1":"He lived the life of a dedicated hedonist.","e1t":"Tam bir haz düşkünü (hedonist) hayatı yaşadı.","e2":"Hedonism (noun).","e2t":"Hazcılık."},{"w":"hegemony","tr":"hegemonya / üstünlük / liderlik","te":"Noun","tt":"İsim","de":"Leadership or dominance, especially by one country or social group over others","dt":"Özellikle bir ülkenin veya grubun diğerleri üzerindeki hakimiyeti/üstünlüğü","e1":"To establish economic hegemony.","e1t":"Ekonomik hegemonya (üstünlük) kurmak.","e2":"The hegemony of the ruling class.","e2t":"Egemen sınıfın hegemonyası."},{"w":"helm","tr":"dümen / yönetim / idare","te":"Noun/Verb","tt":"İsim/Fiil","de":"A tiller or wheel and any associated equipment for steering a ship or boat","dt":"Gemiyi yöneten dümen; veya (mecazi) yönetim/baş","e1":"He is at the helm of the company.","e1t":"Şirketin başında (dümeninde) o var.","e2":"To take the helm.","e2t":"Yönetimi devralmak."},{"w":"hem","tr":"kenar kıvırmak / (giysi) etek ucu / öksürerek dikkat çekmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The edge of a piece of cloth or clothing that has been turned under and sewn","dt":"Giysinin kıvrılıp dikilen kenarı (etek ucu)","e1":"To shorten the hem of a skirt.","e1t":"Eteğin boyunu kısaltmak (etek ucunu kıvırmak).","e2":"To hem and haw (idiom: duraksamak / kaçamak cevap vermek).","e2t":""},{"w":"herbivorous","tr":"otçul / ot yiyen","te":"Adjective","tt":"Sıfat","de":"(Of an animal) feeding on plants","dt":"(Hayvan için) bitkiyle beslenen","e1":"Herbivorous dinosaurs.","e1t":"Otçul dinozorlar.","e2":"Herbivore (noun).","e2t":"Otçul canlı. (Not: Carnivorous"},{"w":"heretic","tr":"sapkın / aykırı inançlı kimse","te":"Noun","tt":"İsim","de":"A person believing in or practicing religious heresy","dt":"Genel inançlara aykırı düşünen veya dinden sapan kişi","e1":"To be branded as a heretic.","e1t":"Sapkın olarak damgalanmak.","e2":"Heretical (adjective).","e2t":"Sapkın / Aykırı."},{"w":"hermit","tr":"münzevi / yalnız yaşayan kimse","te":"Noun","tt":"İsim","de":"A person living in solitude as a religious discipline","dt":"Özellikle dini nedenlerle tek başına yaşayan kişi","e1":"He lives like a hermit in the mountains.","e1t":"Dağlarda bir münzevi gibi yaşıyor.","e2":"Hermitage (noun).","e2t":"Münzevi barınağı. (Not: Eremite ile benzerdir)."},{"w":"hermitage","tr":"münzevi barınağı / inziva yeri","te":"Noun","tt":"İsim","de":"The dwelling of a hermit; or a remote or secluded dwelling","dt":"Münzevinin yaşadığı yer; inziva köşesi","e1":"To retire to a hermitage.","e1t":"Bir inziva yerine çekilmek.","e2":"(Ayrıca St. Petersburg'daki ünlü müze: The State Hermitage Museum).","e2t":""},{"w":"heterodox","tr":"geleneksel olmayan / aykırı / sapkın","te":"Adjective","tt":"Sıfat","de":"Not conforming with accepted or orthodox standards or beliefs","dt":"Genel kabul görmüş standartlara veya inançlara uymayan","e1":"Heterodox views on economics.","e1t":"Ekonomi hakkındaki aykırı (geleneksel olmayan) görüşler.","e2":"Heterodoxy (noun).","e2t":"Aykırı inanç. (Not: Orthodox"},{"w":"heterogeneous","tr":"heterojen / çok sesli / çeşitli öğelerden oluşan","te":"Adjective","tt":"Sıfat","de":"Diverse in character or content","dt":"Karakter veya içerik bakımından çeşitlilik gösteren (farklı türlerden oluşan)","e1":"A heterogeneous population.","e1t":"Farklı etnik/kültürel gruplardan oluşan nüfus.","e2":"A heterogeneous mixture.","e2t":"Heterojen karışım. (Not: Homogeneous"},{"w":"hibernal","tr":"kışla ilgili / kışlık","te":"Adjective","tt":"Sıfat","de":"Of, characteristic of, or occurring in winter","dt":"Kışa ait veya kışın gerçekleşen","e1":"Hibernal sleep (hibernation).","e1t":"Kış uykusu.","e2":"(Not: Hibernal daha nadir kullanılır, Wintry veya Winter daha yaygındır).","e2t":""},{"w":"hibernate","tr":"kış uykusuna yatmak / pasifleşmek","te":"Verb","tt":"Fiil","de":"(Of an animal or plant) spend the winter in a dormant state","dt":"Kışı uykuda (pasif halde) geçirmek","e1":"Bears hibernate during the winter.","e1t":"Ayılar kışın kış uykusuna yatarlar.","e2":"Hibernation (noun).","e2t":"Kış uykusu."},{"w":"hieroglyphic","tr":"hiyeroglif / okunması güç yazı","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"Writing consisting of pictures; or writing that is difficult to read","dt":"Resimlerden oluşan yazı sistemi; veya okunması çok zor (karman çorman) yazı","e1":"Ancient Egyptian hieroglyphics.","e1t":"Antik Mısır hiyeroglifleri.","e2":"His handwriting is practically hieroglyphic.","e2t":"El yazısı resmen hiyeroglif gibi (okunmuyor)."},{"w":"hilarity","tr":"neşe / kahkaha / cümbüş","te":"Noun","tt":"İsim","de":"Extreme amusement, especially when expressed by laughter","dt":"Özellikle kahkahalarla ifade edilen aşırı neşe ve eğlence","e1":"The comedy caused much hilarity in the audience.","e1t":"Komedi seyirciler arasında büyük bir neşeye (kahkahaya) neden oldu.","e2":"Hilarious (adjective).","e2t":"Çok komik."},{"w":"hindmost","tr":"en arkadaki / en sonuncu","te":"Adjective","tt":"Sıfat","de":"Furthest back; last","dt":"En arkada bulunan; en sondaki","e1":"The hindmost wagon of the train.","e1t":"Trenin en arkadaki vagonu.","e2":"\"Devil take the hindmost\" (idiom: herkes başının çaresine baksın).","e2t":""},{"w":"hireling","tr":"paralı asker / uşak / çıkarı için çalışan","te":"Noun","tt":"İsim","de":"A person who is willing to do anything as long as they are paid (derogatory)","dt":"Para karşılığı her şeyi yapmaya hazır olan (genellikle aşağılayıcı)","e1":"He was just a hireling of the corporation.","e1t":"O sadece şirketin paralı bir uşağıydı.","e2":"","e2t":""},{"w":"hirsute","tr":"kıllı / tüylü","te":"Adjective","tt":"Sıfat","de":"Hairy","dt":"Kıllı (vücut için)","e1":"A hirsute chest.","e1t":"Kıllı bir göğüs.","e2":"His hirsute appearance.","e2t":"Tüylü/kıllı görünümü."},{"w":"histrionic","tr":"tiyatral / yapmacık / aşırı duygusal","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Overly theatrical or melodramatic in character or style","dt":"Karakter veya tarz olarak aşırı tiyatral ve yapmacık","e1":"Histrionic outbursts of emotion.","e1t":"Yapmacık (aşırı) duygu patlamaları.","e2":"She is prone to histrionics.","e2t":"O, aşırı (sahne gibi) tepkiler vermeye meyillidir."},{"w":"hoary","tr":"kırlaşmış / çok eski / bayat (espri)","te":"Adjective","tt":"Sıfat","de":"Greyish","dt":"white; or old and trite","e1":"Grimsi beyaz (saç vb.); veya çok eski/bayatlamış","e1t":"A hoary old legend.","e2":"Çok eski bir efsane.","e2t":"Hoary hair."},{"w":"holocaust","tr":"soykırım / büyük kıyım / ateşli felaket","te":"Noun","tt":"İsim","de":"Destruction or slaughter on a mass scale, especially caused by fire or nuclear war","dt":"Özellikle ateş veya nükleer savaş kaynaklı kitlesel yok oluş/katliam","e1":"A nuclear holocaust.","e1t":"Nükleer bir felaket (yok oluş).","e2":"(Büyük harfle 'The Holocaust': Nazi Almanyası'nın Yahudi soykırımı).","e2t":""},{"w":"holster","tr":"tabanca kılıfı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A holder for a handgun, typically made of leather and worn on a belt","dt":"Genellikle kemere takılan deri tabanca kılıfı","e1":"He drew his gun from its holster.","e1t":"Silahını kılıfından çekti.","e2":"","e2t":""},{"w":"homeostasis","tr":"homeostazi / dengelenim","te":"Noun","tt":"İsim","de":"The tendency towards a relatively stable equilibrium between interdependent elements, especially maintained by physiological processes","dt":"Canlılarda iç dengenin (ısı, sıvı vb.) korunması süreci","e1":"The body maintains homeostasis despite external changes.","e1t":"Vücut, dış değişikliklere rağmen iç dengesini korur.","e2":"","e2t":""},{"w":"homespun","tr":"el dokuması / sade / ev yapımı","te":"Adjective","tt":"Sıfat","de":"(Of cloth) spun at home; or simple and unsophisticated","dt":"Evde dokunmuş (kumaş); veya (mecazi) sade, gösterişsiz ve doğal","e1":"Homespun wisdom.","e1t":"Halk bilgeliği (sade ve doğal akıl).","e2":"A homespun wool sweater.","e2t":"El dokuması yün kazak."},{"w":"homily","tr":"dini öğüt / vaaz / sıkıcı nasihat","te":"Noun","tt":"İsim","de":"A religious discourse that is intended primarily for spiritual edification; or a tedious moralizing lecture","dt":"Genellikle dini amaçlı vaaz; veya sıkıcı ve ders verici konuşma","e1":"The priest delivered a short homily.","e1t":"Rahip kısa bir vaaz verdi.","e2":"We had to listen to another homily from our boss.","e2t":"Patronumuzun bir başka (sıkıcı) nasihatini dinlemek zorunda kaldık."},{"w":"homogeneous / homogenous","tr":"homojen / tekdüze / aynı türden","te":"Adjective","tt":"Sıfat","de":"Of the same kind; alike","dt":"Aynı türden olan; her yerinde aynı özelliği gösteren","e1":"A homogeneous society.","e1t":"Tek bir etnik/kültürel yapıdan oluşan (homojen) toplum.","e2":"To mix until the liquid is homogeneous.","e2t":"Sıvı homojen hale gelene kadar karıştırmak."},{"w":"hone","tr":"bilemek / (beceriyi) geliştirmek / bileği taşı","te":"Verb/Noun","tt":"Fiil/İsim","de":"Sharpen (a blade); or refine or perfect (a skill) over a period of time","dt":"(Bıçak vb.) bilemek; veya (beceriyi) zamanla mükemmelleştirmek","e1":"To hone your skills.","e1t":"Becerilerini geliştirmek (keskinleştirmek).","e2":"He used a stone to hone the knife.","e2t":"Bıçağı bilemek için bir taş kullandı."},{"w":"hoodwink","tr":"aldatmak / kandırmak / gözünü boyamak","te":"Verb","tt":"Fiil","de":"Deceive or trick","dt":"Kandırmak veya aldatmak","e1":"Don't let yourself be hoodwinked by his lies.","e1t":"Onun yalanlarına kanmana (gözünü boyamasına) izin verme.","e2":"They were hoodwinked into buying a fake car.","e2t":"Sahte bir arabayı almaları için kandırıldılar."},{"w":"horde","tr":"sürü / kalabalık / ordu (göçebe)","te":"Noun","tt":"İsim","de":"A large group of people","dt":"Büyük ve genellikle düzensiz insan grubu/kalabalığı","e1":"Hordes of tourists in the city center.","e1t":"Şehir merkezindeki turist sürüleri.","e2":"The Golden Horde (history).","e2t":"Altın Orda Devleti."},{"w":"horticulture","tr":"bahçıvanlık / bahçe tarımı","te":"Noun","tt":"İsim","de":"The art or practice of garden cultivation and management","dt":"Bahçe bitkileri yetiştirme sanatı ve bilimi","e1":"He is an expert in horticulture.","e1t":"Bahçe tarımı (bahçıvanlık) konusunda uzmandır.","e2":"Horticultural show.","e2t":"Bahçe bitkileri sergisi."},{"w":"hovel","tr":"baraka / derme çatma kulübe","te":"Noun","tt":"İsim","de":"A small, squalid, unpleasant, or simply","dt":"constructed dwelling","e1":"Küçük, kirli ve derme çatma barınak/ev","e1t":"To live in a tiny hovel.","e2":"Küçücük bir barakada yaşamak.","e2t":""},{"w":"hubris","tr":"aşırı kibir / kendini dev aynasında görme","te":"Noun","tt":"İsim","de":"Excessive pride or self","dt":"confidence, often leading to a downfall","e1":"Genellikle felakete yol açan aşırı gurur ve kibir","e1t":"It was his hubris that caused his failure.","e2":"Onun başarısızlığına neden olan şey aşırı kibriydi.","e2t":"Hubristic (adjective)."},{"w":"hue","tr":"renk tonu / renk / feryat","te":"Noun","tt":"Isim","de":"A color or shade; or the character or aspect of something","dt":"Bir rengin tonu; veya bir şeyin karakteri/yönü","e1":"All the hues of the rainbow.","e1t":"Gökkuşağının tüm renkleri.","e2":"A political hue.","e2t":"Siyasi bir renk (tutum)."},{"w":"humiliate","tr":"aşağılamak / küçük düşürmek / rezil etmek","te":"Verb","tt":"Fiil","de":"Make (someone) feel ashamed and foolish by injuring their dignity and self","dt":"respect","e1":"Birinin onurunu kırarak onu mahcup etmek/küçük düşürmek","e1t":"He was humiliated in front of his colleagues.","e2":"Meslektaşlarının önünde küçük düşürüldü.","e2t":"A humiliating defeat."},{"w":"hummock","tr":"tepecik / tümsek","te":"Noun","tt":"İsim","de":"A small hill, mound, or ridge of earth or ice","dt":"Küçük toprak veya buz tepeciği","e1":"A grassy hummock.","e1t":"Otlarla kaplı küçük bir tepecik.","e2":"","e2t":""},{"w":"humus","tr":"humus / bitkisel toprak","te":"Noun","tt":"İsim","de":"The organic component of soil, formed by the decomposition of leaves and other plant material","dt":"Yaprakların ve bitkilerin çürümesiyle oluşan toprağın organik kısmı","e1":"Soil rich in humus.","e1t":"Humus bakımından zengin toprak.","e2":"(Not: 'Hummus'","e2t":"nohut ezmesi"},{"w":"hurtle","tr":"hızla fırlamak / savrulmak","te":"Verb","tt":"Fiil","de":"Move or cause to move at a great speed, typically in an uncontrolled manner","dt":"Genellikle kontrolsüz bir şekilde çok büyük bir hızla hareket etmek","e1":"The car hurtled down the hill.","e1t":"Araba yokuş aşağı hızla savruldu (fırladı).","e2":"Space debris hurtling through orbit.","e2t":"Yörüngede hızla savrulan uzay çöpleri."},{"w":"hydrophobia","tr":"hidrofobi / su korkusu / kuduz","te":"Noun","tt":"İsim","de":"Extreme or irrational fear of water (especially as a symptom of rabies in humans)","dt":"Suya karşı aşırı korku (insanlarda kuduz belirtisi olarak da bilinir)","e1":"He suffered from hydrophobia.","e1t":"Su korkusu vardı.","e2":"(Kuduz hastalığının diğer adı: Rabies).","e2t":""},{"w":"hypercritical","tr":"aşırı eleştirel / kusur bulmaya çalışan","te":"Adjective","tt":"Sıfat","de":"Excessively critical; finding fault in everything","dt":"Aşırı derecede eleştiren; her şeye kulp takan","e1":"A hypercritical boss.","e1t":"Çok müşkülpesent (her şeyi eleştiren) bir patron.","e2":"Don't be so hypercritical of others.","e2t":"Başkalarına karşı bu kadar eleştirel olma."},{"w":"hypochondriac","tr":"hastalık hastası","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is abnormally anxious about their health","dt":"Sağlığı konusunda aşırı derecede (ve yersizce) endişeli olan kişi","e1":"He is a bit of a hypochondriac.","e1t":"Biraz hastalık hastasıdır.","e2":"Hypochondria (noun).","e2t":"Hastalık hastası olma durumu."},{"w":"hypocritical","tr":"ikiyüzlü / riyakar","te":"Adjective","tt":"Sıfat","de":"Behaving in a way that suggests one has higher standards or more noble beliefs than is the case","dt":"İnanmadığı değerleri savunuyormuş gibi görünen; ikiyüzlü","e1":"It would be hypocritical of me to complain.","e1t":"Şikayet etmem ikiyüzlülük olur.","e2":"Hypocrisy (noun).","e2t":"İkiyüzlülük."},{"w":"ichthyology","tr":"iktiyoloji / balıkbilim","te":"Noun","tt":"İsim","de":"The branch of zoology that deals with fishes","dt":"Balıkları inceleyen zooloji dalı","e1":"Research in ichthyology.","e1t":"Balıkbilim araştırması.","e2":"Ichthyologist (noun).","e2t":"Balık bilimci."},{"w":"iconoclastic","tr":"ikonoklastik / yerleşik değerlere karşı çıkan / gelenek yıkan","te":"Adjective","tt":"Sıfat","de":"Characterized by attack on cherished beliefs or institutions","dt":"Yerleşik inançlara veya kurumlara saldıran; gelenekleri yıkan","e1":"An iconoclastic filmmaker.","e1t":"Alışılagelmiş kuralları yıkan film yönetmeni.","e2":"Iconoclast (noun).","e2t":"Gelenek yıkan kimse."},{"w":"idiom","tr":"deyim / deyiş / dilin kendine özgü yapısı","te":"Noun","tt":"İsim","de":"A group of words established by usage as having a meaning not deducible from those of the individual words","dt":"Kelimelerin gerçek anlamlarından farklı bir anlam taşıyan kalıplaşmış ifade","e1":"\"Kick the bucket\" is a common English idiom.","e1t":"\"Kick the bucket\" (ölmek) yaygın bir İngilizce deyimdir.","e2":"To speak in the local idiom.","e2t":"Yerel dille (ağızla) konuşmak."},{"w":"idiosyncrasy","tr":"kendine özgülük / nev","te":"i şahsına münhasırlık / mizaç","tt":"Noun","de":"İsim","dt":"A mode of behavior or way of thought peculiar to an individual","e1":"Bir bireye özgü olan davranış biçimi veya düşünce tarzı","e1t":"One of his idiosyncrasies is that he always wears two different socks.","e2":"Onun tuhaflıklarından biri her zaman iki farklı çorap giymesidir.","e2t":"Idiosyncratic (adjective)."},{"w":"idolatry","tr":"putperestlik / aşırı hayranlık","te":"Noun","tt":"İsim","de":"The worship of idols; or extreme admiration, love, or reverence for something or someone","dt":"Putlara tapma; veya birine/bir şeye duyulan aşırı (tapınma derecesinde) hayranlık","e1":"To condemn idolatry.","e1t":"Putperestliği kınamak.","e2":"His fans' idolatry was borderline obsessive.","e2t":"Hayranlarının ona olan aşırı tutkusu saplantı sınırındaydı."},{"w":"idyllic","tr":"huzurlu / kusursuz / kırsal ve sakin","te":"Adjective","tt":"Sıfat","de":"(Especially of a time or place) like an idyll; extremely happy, peaceful, or picturesque","dt":"(Özellikle zaman veya yer için) huzur dolu, masalsı ve çok güzel","e1":"An idyllic childhood in the countryside.","e1t":"Kırsalda geçen huzurlu (masalsı) bir çocukluk.","e2":"The setting was idyllic.","e2t":"Ortam muhteşemdi (huzur vericiydi)."},{"w":"igneous","tr":"magmatik / volkanik","te":"Adjective","tt":"Sıfat","de":"(Of rock) having solidified from lava or magma","dt":"Lav veya magmanın katılaşmasıyla oluşan (kayaç)","e1":"Granite is an igneous rock.","e1t":"Granit magmatik bir kayaçtır.","e2":"Igneous activity.","e2t":"Volkanik faaliyet."},{"w":"ignoble","tr":"aşağılık / onur kırıcı / soylu olmayan","te":"Adjective","tt":"Sıfat","de":"Not honorable in character or purpose; or of low birth or common origin","dt":"Karakter veya amaç bakımından onursuz; veya alt tabakadan gelen","e1":"An ignoble action.","e1t":"Aşağılık (onur kırıcı) bir eylem.","e2":"He died an ignoble death.","e2t":"Utanç verici (sefil) bir ölümle öldü."},{"w":"ignominious","tr":"utanç verici / aşağılayıcı / rezilce","te":"Adjective","tt":"Sıfat","de":"Deserving or causing public disgrace or shame","dt":"Kamusal bir utanca veya rezalete neden olan","e1":"An ignominious defeat.","e1t":"Utanç verici (rezilce) bir yenilgi.","e2":"He suffered an ignominious expulsion from the club.","e2t":"Kulüpten aşağılayıcı bir şekilde kovuldu."},{"w":"illusive","tr":"aldatıcı / hayali / yanıltıcı","te":"Adjective","tt":"Sıfat","de":"Deceptive; illusory","dt":"Gerçek olmayan, yanıltıcı","e1":"Illusive hopes of peace.","e1t":"Aldatıcı barış umutları.","e2":"(Not: Illusory daha sık kullanılır).","e2t":""},{"w":"illusory","tr":"aldatıcı / gerçek dışı / yanılsamalı","te":"Adjective","tt":"Sıfat","de":"Based on or producing illusion; not real","dt":"Yanılsamaya dayalı; gerçek olmayan","e1":"The profits turned out to be illusory.","e1t":"Kârların hayali (gerçek dışı) olduğu ortaya çıktı.","e2":"An illusory sense of security.","e2t":"Aldatıcı bir güvenlik hissi."},{"w":"imbalance","tr":"dengesizlik / istikrarsızlık","te":"Noun","tt":"İsim","de":"Lack of proportion or relation between corresponding things","dt":"İlgili şeyler arasındaki oransızlık veya dengesizlik","e1":"Trade imbalance.","e1t":"Ticaret dengesizliği (açığı).","e2":"A chemical imbalance in the brain.","e2t":"Beyindeki kimyasal dengesizlik."},{"w":"imbecility","tr":"aptallık / eblehlik","te":"Noun","tt":"İsim","de":"Great stupidity; or the state of being an imbecile","dt":"Büyük aptallık veya zihinsel gerilik","e1":"It would be pure imbecility to go out in this storm.","e1t":"Bu fırtınada dışarı çıkmak tam bir aptallık olur.","e2":"Imbecile (noun/adj).","e2t":"Aptal / Ebleh."},{"w":"imbroglio","tr":"karmaşa / içinden çıkılmaz durum / keşmekeş","te":"Noun","tt":"İsim","de":"An extremely confused, complicated, or embarrassing situation","dt":"Son derece karışık, karmaşık veya utanç verici durum","e1":"A political imbroglio.","e1t":"Siyasi bir karmaşa.","e2":"To be caught in a legal imbroglio.","e2t":"Hukuki bir keşmekeşin içinde kalmak."},{"w":"immanent","tr":"içkin / her yerde olan / doğasında var olan","te":"Adjective","tt":"Sıfat","de":"Existing or operating within; innate; or (of God) permanently pervading the universe","dt":"(Bir şeyin) içinde var olan; doğasında bulunan; veya (Tanrı için) evrenin her yerinde olan","e1":"Love is immanent in human nature.","e1t":"Sevgi insan doğasında içkindir (vardır).","e2":"(Not: Imminent","e2t":"yakın"},{"w":"immature","tr":"olgunlaşmamış / çocuksu / ham","te":"Adjective","tt":"Sıfat","de":"Not fully developed; or behaving in a way that is typical of someone much younger","dt":"Tam gelişmemiş; veya yaşına göre çocuksu davranan","e1":"Immature behavior.","e1t":"Çocukça davranış.","e2":"An immature fruit.","e2t":"Ham meyve."},{"w":"immemorial","tr":"çok eski / hatırlanamayacak kadar eski","te":"Adjective","tt":"Sıfat","de":"Originating in the distant past; very old","dt":"Çok uzak geçmişe dayanan; ezelden beri gelen","e1":"Since time immemorial.","e1t":"Çok eski zamanlardan (hatırlanamayacak kadar eskiden) beri.","e2":"Immemorial customs.","e2t":"Çok eski gelenekler."},{"w":"immigrate","tr":"göç etmek (bir ülkeye gelmek)","te":"Verb","tt":"Fiil","de":"Come to live permanently in a foreign country","dt":"Yabancı bir ülkeye kalıcı olarak yerleşmek için gelmek","e1":"Many people immigrated to Turkey in the 1920s.","e1t":"1920'lerde birçok kişi Türkiye'ye göç etti (geldi).","e2":"Immigrant (noun).","e2t":"Göçmen (gelen)."},{"w":"immobility","tr":"hareketsizlik / sabitlik","te":"Noun","tt":"İsim","de":"The state of not moving; motionlessness","dt":"Hareket edememe veya hareket etmeme durumu","e1":"To be reduced to total immobility.","e1t":"Tamamen hareketsiz kalmak.","e2":"Immobile (adjective).","e2t":"Hareketsiz."},{"w":"immoderate","tr":"aşırı / ölçüsüz / aşırıya kaçan","te":"Adjective","tt":"Sıfat","de":"Not sensible or restrained; excessive","dt":"Makul veya ölçülü olmayan; aşırı","e1":"Immoderate drinking.","e1t":"Aşırı (ölçüsüz) içki içme.","e2":"Immoderate demands.","e2t":"Haddini aşan (aşırı) talepler."},{"w":"immolate","tr":"kurban etmek / yakarak öldürmek","te":"Verb","tt":"Fiil","de":"Kill or offer as a sacrifice, especially by burning","dt":"Özellikle yakarak kurban etmek veya öldürmek","e1":"He immolated himself in protest.","e1t":"Protesto amacıyla kendini yaktı.","e2":"To immolate a victim on the altar.","e2t":"Bir kurbanı sunak üzerinde kurban etmek."},{"w":"immure","tr":"hapsetmek / duvarlar arasına kapatmak","te":"Verb","tt":"Fiil","de":"Enclose or confine (someone) against their will","dt":"Birini iradesi dışında bir yere (duvarlar arasına) kapatmak veya hapsetmek","e1":"To be immured in a prison cell.","e1t":"Bir hapishane hücresine kapatılmak.","e2":"He immured himself in his study.","e2t":"(Mecazi) Kendini çalışma odasına kapattı."},{"w":"impalpable","tr":"hissedilemez / dokunulamaz / anlaşılması güç","te":"Adjective","tt":"Sıfat","de":"Unable to be felt by touch; or not easily comprehended","dt":"Dokunarak hissedilemeyen (maddi olmayan); veya zihnen kavranması zor","e1":"An impalpable phantom.","e1t":"Dokunulamayan (hayaletvari) bir varlık.","e2":"Impalpable beauty.","e2t":"Elle tutulamayan (soyut) güzellik."},{"w":"impassable","tr":"geçilmez / kapalı (yol)","te":"Adjective","tt":"Sıfat","de":"Impossible to travel along or over","dt":"Üzerinden geçilmesi veya yolculuk yapılması imkansız","e1":"The roads are impassable due to snow.","e1t":"Kar nedeniyle yollar geçit vermiyor (kapalı).","e2":"An impassable swamp.","e2t":"Geçilemez bir bataklık."},{"w":"impassioned","tr":"ateşli / coşkulu / tutkulu","te":"Adjective","tt":"Sıfat","de":"Filled with or showing great emotion","dt":"Büyük bir duygu veya tutkuyla dolu olan","e1":"An impassioned plea for help.","e1t":"Ateşli bir yardım çağrısı.","e2":"He delivered an impassioned speech.","e2t":"Coşkulu bir konuşma yaptı. (Not: Passionate ile benzerdir)."},{"w":"impassive","tr":"duygusuz / ifadesiz / istifini bozmayan","te":"Adjective","tt":"Sıfat","de":"Not feeling or showing emotion","dt":"Duygu hissetmeyen veya belli etmeyen (donuk)","e1":"His face remained impassive.","e1t":"Yüzü ifadesiz kaldı.","e2":"She showed an impassive reaction to the news.","e2t":"Haberlere karşı tepkisiz (duygusuz) bir tepki verdi."},{"w":"impeach","tr":"(kamu görevlisini) suçlamak / (tanığın) güvenirliğini sorgulamak","te":"Verb","tt":"Fiil","de":"Call into question the integrity or validity of; or charge with misconduct","dt":"Birinin dürüstlüğünü sorgulamak; veya (yüksek görevliyi) görev suçuyla itham etmek","e1":"To impeach a president.","e1t":"Bir başkanı azletmek (suçlamak).","e2":"To impeach the testimony of a witness.","e2t":"Bir tanığın ifadesinin doğruluğunu çürütmek (sorgulamak)."},{"w":"impecunious","tr":"meteliksiz / beş parasız / fakir","te":"Adjective","tt":"Sıfat","de":"Having little or no money","dt":"Hiç parası olmayan; yoksul","e1":"An impecunious student.","e1t":"Meteliksiz bir öğrenci.","e2":"To find oneself in an impecunious state.","e2t":"Kendini beş parasız bir durumda bulmak."},{"w":"impede","tr":"engellemek / geciktirmek / köstek olmak","te":"Verb","tt":"Fiil","de":"Delay or prevent (someone or something) by obstructing them; hinder","dt":"Birini veya bir şeyi engelleyerek geciktirmek","e1":"Technical difficulties impeded our progress.","e1t":"Teknik zorluklar ilerlememizi engelledi.","e2":"To impede the flow of traffic.","e2t":"Trafik akışını yavaşlatmak (aksatmak)."},{"w":"impel","tr":"zorlamak / itmek / harekete geçirmek","te":"Verb","tt":"Fiil","de":"Drive, force, or urge (someone) to do something","dt":"Birini bir şey yapmaya sevk etmek veya zorlamak","e1":"Hunger impelled him to steal.","e1t":"Açlık onu çalmaya sevk etti (zorladı).","e2":"I felt impelled to speak the truth.","e2t":"Doğruyu söylemek zorunda (mecbur) hissettim. (Not: Impulse"},{"w":"impenetrable","tr":"nüfuz edilemez / girilemez / anlaşılamaz","te":"Adjective","tt":"Sıfat","de":"Impossible to pass through or enter; or impossible to understand","dt":"İçinden geçilmesi veya girilmesi imkansız; veya anlaşılması imkansız","e1":"An impenetrable jungle.","e1t":"Balta girmemiş (girilemez) orman.","e2":"Impenetrable darkness.","e2t":"Kapkaranlık (göz gözü görmez)."},{"w":"impenitent","tr":"pişmanlık duymayan / tövbe etmeyen","te":"Adjective","tt":"Sıfat","de":"Not feeling shame or regret about one's actions or attitudes","dt":"Eylemlerinden dolayı utanç veya pişmanlık duymayan","e1":"An impenitent criminal.","e1t":"Pişmanlık duymayan suçlu.","e2":"He remained impenitent to the end.","e2t":"Sonuna kadar tövbe etmedi (pişman olmadı)."},{"w":"imperceptible","tr":"algılanamaz / fark edilemez / çok küçük","te":"Adjective","tt":"Sıfat","de":"So slight, gradual, or subtle as not to be perceived","dt":"Algılanamayacak kadar hafif, yavaş veya küçük olan","e1":"An imperceptible change in temperature.","e1t":"Sıcaklıkta fark edilemez bir değişim.","e2":"Imperceptibly (adverb).","e2t":"Fark ettirmeden / Yavaş yavaş."},{"w":"imperious","tr":"kibirli / emredici / otoriter","te":"Adjective","tt":"Sıfat","de":"Assuming power or authority without justification; arrogant and domineering","dt":"Haksız yere otorite taslayan; kibirli ve emredici","e1":"She sent him away with an imperious gesture.","e1t":"Onu emredici bir el hareketiyle savdı.","e2":"An imperious tone of voice.","e2t":"Otoriter (üstten bakan) bir ses tonu."},{"w":"imperturbable","tr":"sarsılmaz / soğukkanlı / istifini bozmayan","te":"Adjective","tt":"Sıfat","de":"Unable to be upset or excited; calm","dt":"Heyecanlanmayan veya dengesi bozulmayan (çok sakin)","e1":"He remained imperturbable even in a crisis.","e1t":"Kriz anında bile istifini bozmadı (sarsılmadı).","e2":"An imperturbable confidence.","e2t":"Sarsılmaz bir güven."},{"w":"impervious","tr":"etkilenmez / geçirimsiz / duyarsız","te":"Adjective","tt":"Sıfat","de":"Not allowing fluid to pass through; or unable to be affected by","dt":"Sıvı geçirmeyen; veya (eleştiri vb.'den) etkilenmeyen","e1":"A coat impervious to rain.","e1t":"Yağmur geçirmeyen palto.","e2":"He seems impervious to criticism.","e2t":"Eleştirilere karşı duyarsız (etkilenmez) görünüyor."},{"w":"impetuous","tr":"düşüncesizce yapılan / aceleci / fevri","te":"Adjective","tt":"Sıfat","de":"Acting or done quickly and without thought or care","dt":"Sonucunu düşünmeden, aniden yapılan","e1":"An impetuous decision.","e1t":"Fevri (düşüncesizce) bir karar.","e2":"Her impetuous nature often got her into trouble.","e2t":"Aceleci yapısı onu sık sık başını belaya sokardı."},{"w":"impiety","tr":"saygısızlık (dini) / dinsizlik","te":"Noun","tt":"İsim","de":"Lack of piety or reverence, especially for a god","dt":"Özellikle Tanrı'ya veya kutsal değerlere karşı saygı eksikliği","e1":"He was accused of impiety.","e1t":"Kutsal değerlere saygısızlıkla suçlandı.","e2":"Impious (adjective).","e2t":"Saygısız / Dinsiz."},{"w":"impinge","tr":"çarpmak / olumsuz etkilemek / tecavüz etmek","te":"Verb","tt":"Fiil","de":"Have an effect or impact, especially a negative one; or to encroach","dt":"Özellikle olumsuz bir etkide bulunmak; veya (hakka vb.) tecavüz etmek","e1":"High taxes impinge on our lifestyle.","e1t":"Yüksek vergiler yaşam tarzımızı (olumsuz) etkiliyor.","e2":"The sound impinged on my eardrums.","e2t":"Ses kulak zarlarıma vurdu (çarptı)."},{"w":"implacable","tr":"yatıştırılamaz / amansız / sarsılmaz","te":"Adjective","tt":"Sıfat","de":"Relentless; unstoppable; or unable to be appeased","dt":"Yatıştırılması imkansız; durdurulamaz veya amansız","e1":"An implacable enemy.","e1t":"Amansız (asla barışmaz) bir düşman.","e2":"Implacable logic.","e2t":"Sarsılmaz (katı) mantık."},{"w":"implicate","tr":"bulaştırmak / (suça) karıştırmak / ima etmek","te":"Verb","tt":"Fiil","de":"Show (someone) to be involved in a crime; or to convey a meaning indirectly","dt":"Birinin bir suça karıştığını göstermek; veya dolaylı yoldan ima etmek","e1":"The evidence implicates him in the robbery.","e1t":"Kanıtlar onun soyguna karıştığını gösteriyor.","e2":"Implication (noun).","e2t":"İma / Çıkarım / Bulaşma."},{"w":"implode","tr":"içeri doğru patlamak / çökmek","te":"Verb","tt":"Fiil","de":"Collapse or cause to collapse violently inwards","dt":"Şiddetli bir şekilde içe doğru çökmek veya patlamak","e1":"The vacuum tube imploded.","e1t":"Vakum tüpü içe doğru patladı.","e2":"The whole economic system could implode.","e2t":"Tüm ekonomik sistem (içten) çökebilir."},{"w":"implore","tr":"yalvarmak / istirham etmek","te":"Verb","tt":"Fiil","de":"Beg someone earnestly or desperately to do something","dt":"Birinden bir şeyi yapması için canı gönülden (çaresizce) yalvarmak","e1":"\"Help me,\" she implored.","e1t":"\"Bana yardım et,\" diye yalvardı.","e2":"I implore you to change your mind.","e2t":"Kararınızı değiştirmeniz için size yalvarıyorum."},{"w":"impolitic","tr":"akılsızca / düşüncesiz / yersiz","te":"Adjective","tt":"Sıfat","de":"Failing to possess or display prudence; unwise","dt":"Öngörüsüz; akıllıca olmayan (yersiz)","e1":"It would be impolitic to ignore their advice.","e1t":"Onların tavsiyesini görmezden gelmek akılsızca (stratejik olarak yanlış) olur.","e2":"An impolitic remark.","e2t":"Düşüncesizce söylenmiş bir söz."},{"w":"importunate","tr":"ısrarcı / taciz eden / rahatsızlık veren","te":"Adjective","tt":"Sıfat","de":"Persistent, especially to the point of annoyance or intrusion","dt":"Özellikle rahatsız edici derecede ısrarcı","e1":"Importunate creditors.","e1t":"Kapıdan ayrılmayan (ısrarcı) alacaklılar.","e2":"To be troubled by importunate questions.","e2t":"Baştan savılamayan sorularla rahatsız edilmek."},{"w":"importune","tr":"ısrarla istemek / musallat olmak / taciz etmek","te":"Verb","tt":"Fiil","de":"Ask (someone) pressingly and persistently for or to do something","dt":"Birinden ısrarla ve sürekli bir şey istemek (rahatsız ederek)","e1":"She importuned her parents for a new car.","e1t":"Yeni bir araba için ailesine musallat oldu (ısrar etti).","e2":"","e2t":""},{"w":"imprecation","tr":"beddua / lanet","te":"Noun","tt":"İsim","de":"A spoken curse","dt":"Sözlü olarak dile getirilen lanet veya beddua","e1":"To utter an imprecation.","e1t":"Bir beddua savurmak.","e2":"Imprecate (verb).","e2t":"Lanet okumak."},{"w":"impregnate","tr":"hamile bırakmak / aşılamak / (sıvı vb.) emdirmek","te":"Verb","tt":"Fiil","de":"Make (a woman or female animal) pregnant; or to soak or saturate","dt":"Hamile bırakmak; veya bir şeyi bir sıvıya/fikre doyurmak (emdirmek)","e1":"The wood was impregnated with a preservative.","e1t":"Oduna koruyucu bir madde emdirildi.","e2":"To impregnate someone with new ideas.","e2t":"Birine yeni fikirler aşılamak."},{"w":"improvident","tr":"öngörüsüz / tedbirsiz / savurgan","te":"Adjective","tt":"Sıfat","de":"Not having or showing foresight; spendthrift or thoughtless","dt":"Geleceği düşünmeyen; tedbirsiz veya savurgan","e1":"Improvident lifestyle.","e1t":"Yarını düşünmeden yaşanan (savurgan) hayat.","e2":"(Not: Provident","e2t":"tedbirli"},{"w":"improvise","tr":"doğaçlama yapmak / eldeki imkanlarla yapmak","te":"Verb","tt":"Fiil","de":"Create and perform (music, drama, or verse) spontaneously or without preparation","dt":"Hazırlıksız olarak (o an) üretmek ve sunmak","e1":"To improvise a meal from leftovers.","e1t":"Kalan yemeklerden (o an uydurarak) bir öğün hazırlamak.","e2":"A jazz musician who can improvise for hours.","e2t":"Saatlerce doğaçlama yapabilen caz müzisyeni."},{"w":"imprudent","tr":"tedbirsiz / ihtiyatsız / akılsızca","te":"Adjective","tt":"Sıfat","de":"Not showing care for the consequences of an action; rash","dt":"Eylemlerinin sonucunu düşünmeyen; tedbirsiz","e1":"It would be imprudent to invest all your money in one company.","e1t":"Tüm paranı tek bir şirkete yatırmak tedbirsizlik (akılsızlık) olur.","e2":"Imprudence (noun).","e2t":"Tedbirsizlik. (Not: Prudent"},{"w":"impudence","tr":"küstahlık / arsızlık / saygısızlık","te":"Noun","tt":"İsim","de":"The quality of being impudent; impertinence","dt":"Saygısız ve utanmaz olma durumu","e1":"He had the impudence to talk back.","e1t":"Cevap verecek kadar küstahlık (hadsizlik) gösterdi.","e2":"Impudent (adjective).","e2t":"Küstah / Arsız."},{"w":"impugn","tr":"doğruluğunu sorgulamak / itiraz etmek / çürütmeye çalışmak","te":"Verb","tt":"Fiil","de":"Dispute the truth, validity, or honesty of (a statement or motive)","dt":"(Bir ifadenin veya niyetin) doğruluğunu veya dürüstlüğünü tartışmaya açmak","e1":"To impugn someone's motives.","e1t":"Birinin niyetini sorgulamak (altında bir şey aramak).","e2":"The lawyer tried to impugn the witness's testimony.","e2t":"Avukat, tanığın ifadesinin güvenirliğini sarsmaya çalıştı."},{"w":"impute","tr":"atfetmek /","te":"e yüklemek (suç vb.)","tt":"Verb","de":"Fiil","dt":"Represent (something, especially something undesirable) as being done, caused, or possessed by someone","e1":"(Özellikle kötü bir şeyi) birine mal etmek veya yüklemek","e1t":"To impute a crime to an innocent man.","e2":"Bir suçu masum bir adama yüklemek.","e2t":"Imputed motives."},{"w":"inalienable","tr":"devredilemez / vazgeçilemez (hak vb.)","te":"Adjective","tt":"Sıfat","de":"Unable to be taken away from or given away by the possessor","dt":"Sahibinden geri alınamayan veya başkasına devredilemeyen","e1":"Inalienable human rights.","e1t":"Vazgeçilemez (devredilemez) insan hakları.","e2":"","e2t":""},{"w":"incandescent","tr":"akkor / parlayan / çok parlak","te":"Adjective","tt":"Sıfat","de":"Emitting light as a result of being heated; or full of strong emotion","dt":"Isı etkisiyle ışık saçan; veya (mecazi) çok tutkulu/parlak","e1":"Incandescent light bulb.","e1t":"Akkor lamba.","e2":"Incandescent with rage.","e2t":"Öfkeden kıpkırmızı kesilmiş."},{"w":"incantation","tr":"büyü sözü / tekerleme / afsun","te":"Noun","tt":"İsim","de":"A series of words said as a magic spell or charm","dt":"Büyü yapmak için söylenen sözler dizisi","e1":"To recite an incantation.","e1t":"Bir büyü sözü okumak.","e2":"The priest's rhythmic incantations.","e2t":"Rahibin ritmik duaları/sözleri."},{"w":"incarcerate","tr":"hapsetmek / kapatmak","te":"Verb","tt":"Fiil","de":"Imprison or confine","dt":"Hapsetmek veya bir yere kapatmak","e1":"He was incarcerated for ten years.","e1t":"On yıl boyunca hapis yattı.","e2":"Incarceration (noun).","e2t":"Hapse atılma."},{"w":"incarnate","tr":"somutlaşmış / ete kemiğe bürünmüş / temsil eden","te":"Adjective/Verb","tt":"Embodied in flesh; in human form; or to be the living embodiment of a quality","de":"İnsan formunda; veya bir niteliğin canlı timsali olan","dt":"He is the devil incarnate.","e1":"O, ete kemiğe bürünmüş (vücut bulmuş) bir şeytandır.","e1t":"To incarnate an idea in a work of art.","e2":"Bir fikri sanat eserinde somutlaştırmak.","e2t":""},{"w":"incinerate","tr":"yakıp kül etmek / (çöp vb.) yakmak","te":"Verb","tt":"Fiil","de":"Destroy (something, especially waste material) by burning","dt":"Bir şeyi (özellikle atıkları) yakarak yok etmek","e1":"Most medical waste is incinerated.","e1t":"Tıbbi atıkların çoğu yakılarak imha edilir.","e2":"Incineration (noun).","e2t":"Yakma."},{"w":"incipient","tr":"başlangıç halindeki / yeni beliren","te":"Adjective","tt":"Sıfat","de":"In an initial stage; beginning to happen or develop","dt":"Henüz başlangıç aşamasında olan; yeni ortaya çıkan","e1":"Incipient signs of recovery.","e1t":"İyileşmenin ilk belirtileri.","e2":"An incipient cold.","e2t":"Başlangıç aşamasında (yeni başlayan) bir nezle."},{"w":"incisive","tr":"keskin / etkili / delici (zeka/söz)","te":"Adjective","tt":"Sıfat","de":"(Of a person or mental process) intelligently analytical and clear","dt":"thinking; or direct and decisive","e1":"(Zeka veya analiz için) keskin, net ve etkili","e1t":"Incisive comments.","e2":"Keskin ve yerinde yorumlar.","e2t":"She has an incisive mind."},{"w":"inclement","tr":"sert / fırtınalı (hava) / merhametsiz","te":"Adjective","tt":"Sıfat","de":"(Of the weather) unpleasantly cold or wet; or lacking mercy","dt":"(Hava için) nahoş şekilde sert, soğuk veya fırtınalı","e1":"The match was cancelled due to inclement weather.","e1t":"Maç, elverişsiz (sert) hava koşulları nedeniyle iptal edildi.","e2":"(Not: Clement","e2t":"yumuşak/merhametli"},{"w":"incommodious","tr":"dar / ferah olmayan / rahatsız","te":"Adjective","tt":"Sıfat","de":"Causing inconvenience or discomfort; or not spacious","dt":"Rahatsızlık veren; veya geniş olmayan (dar ve sıkışık)","e1":"A cramped and incommodious apartment.","e1t":"Basık ve dar bir daire. (Not: Commodious","e2":"ferah","e2t":"zıttıdır)."},{"w":"incomparable","tr":"kıyaslanamaz / eşsiz / rakipsiz","te":"Adjective","tt":"Sıfat","de":"Without an equal in quality or extent; matchless","dt":"Benzeri olmayan; kalitede rakipsiz","e1":"Incomparable beauty.","e1t":"Kıyaslanamaz (eşsiz) güzellik.","e2":"The two situations are incomparable.","e2t":"İki durum birbiriyle kıyaslanamaz (bir tutulamaz)."},{"w":"incompatible","tr":"uyumsuz / bağdaşmayan","te":"Adjective","tt":"Sıfat","de":"(Of two things) so different in nature as to be incapable of coexisting","dt":"Bir arada bulunamayacak kadar farklı; uyumsuz","e1":"Their beliefs are incompatible.","e1t":"İnançları birbirine zıt (uyumsuz).","e2":"Incompatible software versions.","e2t":"Uyumsuz yazılım versiyonları."},{"w":"inconceivable","tr":"akıl almaz / hayal edilemez / inanılmaz","te":"Adjective","tt":"Sıfat","de":"Not capable of being imagined or grasped mentally; unbelievable","dt":"Zihnen kavranması veya hayal edilmesi imkansız olan","e1":"It is inconceivable that she would lie to me.","e1t":"Bana yalan söylemesi akıl almaz (inanılmaz) bir şey.","e2":"An inconceivable distance.","e2t":"Hayal edilemez bir mesafe."},{"w":"inconclusive","tr":"sonuçsuz / kesin olmayan","te":"Adjective","tt":"Sıfat","de":"Not leading to a firm conclusion or result; not ending doubt","dt":"Kesin bir sonuca vardırmayan; şüpheleri gidermeyen","e1":"The evidence was inconclusive.","e1t":"Kanıtlar yetersizdi (kesin bir sonuca ulaştırmadı).","e2":"An inconclusive test result.","e2t":"Belirsiz test sonucu."},{"w":"inconsistency","tr":"tutarsızlık / çelişki / istikrarsızlık","te":"Noun","tt":"İsim","de":"The property of being self","dt":"contradictory; or lack of uniformity or stability","e1":"Kendiyle çelişme durumu; veya tekdüzelik/istikrar eksikliği","e1t":"Inconsistencies in his testimony.","e2":"İfadesindeki tutarsızlıklar.","e2t":"The inconsistency of the service."},{"w":"incontinent","tr":"(ihtiyaçlarını) tutamayan / özdenetimi olmayan","te":"Adjective","tt":"Sıfat","de":"Lacking self","dt":"restraint (especially regarding sexual desire); or unable to control bladder/bowels","e1":"Özdenetimi olmayan; veya boşaltım sistemini kontrol edemeyen","e1t":"To become incontinent with age.","e2":"Yaşla birlikte (idrar vb.) tutamaz hale gelmek.","e2t":"Incontinence (noun)."},{"w":"incontrovertible","tr":"tartışılamaz / su götürmez / kesin","te":"Adjective","tt":"Sıfat","de":"Not able to be denied or disputed","dt":"İnkar edilmesi veya tartışılması imkansız olan","e1":"Incontrovertible proof of his guilt.","e1t":"Suçluluğunun tartışılamaz (kesin) kanıtı.","e2":"An incontrovertible fact.","e2t":"Su götürmez bir gerçek."},{"w":"incorrigible","tr":"ıslah olmaz / düzelmez","te":"Adjective","tt":"Sıfat","de":"(Of a person or their behavior) not able to be improved, changed, or reformed","dt":"(Kişi veya davranış için) düzeltilmesi veya yola getirilmesi imkansız","e1":"An incorrigible liar.","e1t":"Islah olmaz bir yalancı.","e2":"He is an incorrigible romantic.","e2t":"O, iflah olmaz bir romantiktir."},{"w":"incredulity","tr":"inanmama / şüphecilik / hayret","te":"Noun","tt":"İsim","de":"The state of being unwilling or unable to believe something","dt":"Bir şeye inanmakta güçlük çekme veya inanmama durumu","e1":"He stared at her in incredulity.","e1t":"Hayretle (inanmayarak) ona baktı.","e2":"To greet the news with incredulity.","e2t":"Haberleri şüpheyle (inanmayarak) karşılamak."},{"w":"incrustation / encrustation","tr":"kabuk bağlama / tabaka / süsleme","te":"Noun","tt":"İsim","de":"A hard coating or layer of something; or a decorative layer","dt":"Sert bir dış tabaka veya kabuk; veya süsleme tabakası","e1":"An incrustation of salt on the rocks.","e1t":"Kayaların üzerindeki tuz tabakası.","e2":"To remove the incrustation.","e2t":"Kabuğu (tabakayı) temizlemek."},{"w":"inculcate","tr":"(fikir/değer) aşılamak / telkin etmek","te":"Verb","tt":"Fiil","de":"Instill (an attitude, idea, or habit) by persistent instruction","dt":"Bir fikri veya değeri sürekli tekrarlayarak birine aşılamak (öğretmek)","e1":"To inculcate a sense of responsibility in children.","e1t":"Çocuklara sorumluluk duygusu aşılamak.","e2":"The values inculcated by his parents.","e2t":"Ailesi tarafından kendisine aşılanan değerler."},{"w":"incumbent","tr":"görevdeki / zorunlu / üzerine vazife","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Necessary for (someone) as a duty or responsibility; or the holder of an office","dt":"Birinin görevi/yükümlülüğü olan; veya mevcut görevli","e1":"It is incumbent upon you to tell the truth.","e1t":"Doğruyu söylemek senin görevin (üzerine borç).","e2":"The incumbent president.","e2t":"Görevdeki (mevcut) başkan."},{"w":"indefatigable","tr":"yorulmak bilmez / azimli","te":"Adjective","tt":"Sıfat","de":"(Of a person or their efforts) persisting tirelessly","dt":"(Kişi veya çaba için) hiç yorulmadan, azimle devam eden","e1":"An indefatigable worker.","e1t":"Yorulmak bilmez bir çalışan.","e2":"Her indefatigable spirit.","e2t":"Onun pes etmeyen ruhu."},{"w":"indelible","tr":"silinmez / kalıcı","te":"Adjective","tt":"Sıfat","de":"(Of ink or a mark) making marks that cannot be removed; or not able to be forgotten","dt":"(Mürekkep/iz için) silinmez; veya unutulmaz (kalıcı)","e1":"Indelible ink.","e1t":"Silinmez mürekkep.","e2":"The experience left an indelible impression on him.","e2t":"Deneyim onda silinmez bir iz bıraktı."},{"w":"indemnify","tr":"tazmin etmek / güvence altına almak / zararı karşılamak","te":"Verb","tt":"Fiil","de":"Compensate (someone) for harm or loss; or secure against legal liability","dt":"Birinin zararını karşılamak; veya (yasal sorumluluğa karşı) güvence vermek","e1":"The company will indemnify you for any losses.","e1t":"Şirket tüm kayıplarınızı tazmin edecektir.","e2":"To indemnify someone against loss.","e2t":"Birini zarara karşı sigortalamak."},{"w":"indentation","tr":"girinti / çentik / paragraf başı","te":"Noun","tt":"İsim","de":"A deep recess in a shoreline; or a notch on an edge; or a space left at the beginning of a line","dt":"Kıyıdaki girinti; veya kenardaki çentik; veya yazıdaki paragraf başı boşluğu","e1":"The coast is marked by several indentations.","e1t":"Kıyı şeridinde birkaç girinti bulunmaktadır.","e2":"An indentation in the metal.","e2t":"Metaldeki bir çöküntü (iz)."},{"w":"indenture","tr":"sözleşme (çıraklık vb.) / senet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A formal legal agreement, contract, or document, in particular historically one binding an apprentice to a master","dt":"Özellikle çırağı ustaya bağlayan tarihi resmi sözleşme","e1":"Indentured labor.","e1t":"Sözleşmeli (bağımlı) işçilik.","e2":"To sign an indenture.","e2t":"Bir senet/sözleşme imzalamak."},{"w":"indeterminate","tr":"belirsiz / net olmayan / kesinleşmemiş","te":"Adjective","tt":"Sıfat","de":"Not exactly known, established, or defined","dt":"Tam olarak bilinmeyen veya tanımlanmamış","e1":"A woman of indeterminate age.","e1t":"Yaşı kestirilemeyen (belirsiz) bir kadın.","e2":"The date is still indeterminate.","e2t":"Tarih henüz kesinleşmedi."},{"w":"indicative","tr":"göstergesi olan / belirten / haber veren","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Serving as a sign or indication of something","dt":"Bir şeyin işareti veya göstergesi olan","e1":"High fever is indicative of an infection.","e1t":"Yüksek ateş bir enfeksiyonun göstergesidir.","e2":"The indicative mood (grammar).","e2t":"Haber kipi (bildirme kipi)."},{"w":"indigence","tr":"aşırı yoksulluk / sefalet / muhtaçlık","te":"Noun","tt":"İsim","de":"A state of extreme poverty","dt":"Temel ihtiyaçları karşılayamayacak kadar büyük fakirlik","e1":"He was reduced to indigence after the bank failed.","e1t":"Banka iflas edince sefalete düştü.","e2":"To live in a state of indigence.","e2t":"Yoksulluk içinde yaşamak."},{"w":"indignant","tr":"öfkeli (haksızlık karşısında) / kırgın / içerlemiş","te":"Adjective","tt":"Sıfat","de":"Feeling or showing anger or annoyance at what is perceived as unfair treatment","dt":"Haksızlık veya adaletsizlik karşısında duyulan öfke","e1":"He was indignant at the suggestion that he had lied.","e1t":"Yalan söylediği imasına çok öfkelendi (içerledi).","e2":"An indignant letter of protest.","e2t":"Öfkeli bir protesto mektubu."},{"w":"indignity","tr":"aşağılanma / hakaret / onur kırıcı davranış","te":"Noun","tt":"İsim","de":"Treatment or circumstances that cause one to feel shame or to lose one's dignity","dt":"Birinin onurunu kıran veya onu küçük düşüren muamele","e1":"He suffered the indignity of being fired in public.","e1t":"Herkesin içinde kovulmanın aşağılanmasını yaşadı.","e2":"To endure insults and indignities.","e2t":"Hakaretlere ve aşağılanmalara katlanmak."},{"w":"indissoluble","tr":"parçalanamaz / bozulamaz / çözülemez","te":"Adjective","tt":"Sıfat","de":"Unable to be destroyed; lasting; or unable to be dissolved","dt":"Yok edilemeyen; kalıcı veya (sıvıda) çözülemeyen","e1":"An indissoluble bond of friendship.","e1t":"Arkadaşlığın koparılamaz (bozulamaz) bağı.","e2":"Indissoluble substances.","e2t":"Çözünmeyen maddeler."},{"w":"indite","tr":"yazmak / kaleme almak (şiir/mektup)","te":"Verb","tt":"Fiil","de":"Write; compose","dt":"(Özellikle edebi bir şeyi) yazmak veya bestelemek","e1":"He indited a long poem to his beloved.","e1t":"Sevdiğine uzun bir şiir kaleme aldı (yazdı).","e2":"(Not: 'Indict'","e2t":"suçlamak"},{"w":"indoctrinate","tr":"(fikir) aşılamak / beynini yıkamak","te":"Verb","tt":"Fiil","de":"Teach (a person or group) to accept a set of beliefs uncritically","dt":"Birine belirli bir inanç sistemini sorgusuz kabul etmesi için fikir aşılamak","e1":"Children were indoctrinated from a young age.","e1t":"Çocuklara küçük yaştan itibaren fikir aşılandı (beyinleri yıkandı).","e2":"Indoctrination (noun).","e2t":"Beyin yıkama / Fikir aşılama."},{"w":"inductance","tr":"endüktans / özindükleme","te":"Noun","tt":"İsim","de":"The property of an electric conductor or circuit that causes an electromotive force to be generated by a change in the current flowing through it","dt":"Bir elektrik devresinde akım değişimine karşı oluşan direnç özelliği","e1":"The unit of inductance is the henry.","e1t":"Endüktans birimi henry'dir.","e2":"","e2t":""},{"w":"ineffable","tr":"kelimelerle anlatılamaz / tarif edilemez","te":"Adjective","tt":"Sıfat","de":"Too great or extreme to be expressed or described in words","dt":"Sözcüklerin yetersiz kaldığı kadar muazzam veya kutsal","e1":"Ineffable joy.","e1t":"Tarif edilemez bir neşe.","e2":"The ineffable name of God.","e2t":"Tanrı'nın (kutsallığından dolayı) ağza alınamaz adı."},{"w":"ineffectual","tr":"etkisiz / sonuç vermeyen / beceriksiz","te":"Adjective","tt":"Sıfat","de":"Not producing any or the desired effect","dt":"İstenen sonucu vermeyen (yetersiz)","e1":"An ineffectual leader.","e1t":"Etkisiz (pasif) bir lider.","e2":"The search proved ineffectual.","e2t":"Arama çalışmaları sonuçsuz kaldı."},{"w":"ineluctable","tr":"kaçınılmaz / mukadder","te":"Adjective","tt":"Sıfat","de":"Unable to be resisted or avoided; inescapable","dt":"Karşı konulamaz veya kaçınılamaz olan","e1":"The ineluctable passage of time.","e1t":"Zamanın kaçınılmaz akışı.","e2":"An ineluctable fate.","e2t":"Kaçınılmaz bir kader."},{"w":"inequity","tr":"adaletsizlik / haksızlık","te":"Noun","tt":"İsim","de":"Lack of fairness or justice","dt":"Hakkaniyet veya adalet eksikliği","e1":"Inequities in the healthcare system.","e1t":"Sağlık sistemindeki eşitsizlikler (haksızlıklar).","e2":"(Not: Equity","e2t":"hakkaniyet"},{"w":"inexorable","tr":"durdurulamaz / amansız / ikna edilemez","te":"Adjective","tt":"Sıfat","de":"Impossible to stop or prevent; or (of a person) impossible to persuade","dt":"Durdurulması veya engellenmesi imkansız; amansız","e1":"The inexorable progress of the disease.","e1t":"Hastalığın durdurulamaz ilerleyişi.","e2":"Inexorable logic.","e2t":"Amansız (katı) mantık."},{"w":"infatuated","tr":"kara sevdalı / aşırı tutulmuş / büyülenmiş","te":"Adjective","tt":"Sıfat","de":"Possessed with an intense but short","dt":"lived passion or admiration for someone","e1":"Biriyle (genellikle kısa süreli ama çok yoğun) kafayı bozmuş derecede ilgili","e1t":"He was infatuated with his new colleague.","e2":"Yeni meslektaşına kara sevdalı gibi tutulmuştu.","e2t":"Infatuation (noun)."},{"w":"infirmity","tr":"halsizlik / hastalık / zayıflık","te":"Noun","tt":"İsim","de":"Physical or mental weakness","dt":"Fiziksel veya zihinsel zayıflık; sakatlık","e1":"The infirmities of old age.","e1t":"Yaşlılığın getirdiği hastalıklar (zayıflıklar).","e2":"Infirm (adjective).","e2t":"Halsiz / Sakat."},{"w":"influx","tr":"akın / giriş / doluşma","te":"Noun","tt":"İsim","de":"An arrival or entry of large numbers of people or things","dt":"Çok sayıda insan veya şeyin bir yere girmesi/gelmesi","e1":"A sudden influx of tourists.","e1t":"Ani bir turist akını.","e2":"The influx of foreign capital.","e2t":"Yabancı sermaye girişi."},{"w":"infraction","tr":"kural ihlali / çiğneme","te":"Noun","tt":"İsim","de":"A violation or infringement of a law or agreement","dt":"Bir yasanın, kuralın veya antlaşmanın ihlali","e1":"A minor infraction of the rules.","e1t":"Kuralların küçük bir ihlali.","e2":"","e2t":""},{"w":"infusion","tr":"infüzyon / demleme / şırınga etme / (para vb.) akıtma","te":"Noun","tt":"İsim","de":"A drink or extract prepared by soaking tea or herbs in liquid; or the introduction of a new element","dt":"Bitki çayı (demleme); veya yeni bir kaynağın (para vb.) sisteme dahil edilmesi","e1":"Herbal infusions.","e1t":"Bitki çayları.","e2":"A massive infusion of cash into the business.","e2t":"İşletmeye yüklü miktarda nakit akışı."},{"w":"ingenuous","tr":"saf / dürüst / açık yürekli","te":"Adjective","tt":"Sıfat","de":"(Of a person or action) innocent and unsuspecting","dt":"Hiçbir art niyeti olmayan, çocuksu bir dürüstlükle davranan","e1":"An ingenuous smile.","e1t":"Saf ve içten bir gülümseme.","e2":"He gave an ingenuous account of what happened.","e2t":"Olanları tüm çıplaklığı ve dürüstlüğüyle anlattı. (Not: Ingenious"},{"w":"inhibited","tr":"çekingen / tutuk / baskılanmış","te":"Adjective","tt":"Sıfat","de":"Unable to act in a relaxed and natural way because of self","dt":"consciousness or mental restraint","e1":"Kendini rahat hissedemeyen, içindeki duyguları bastıran","e1t":"He felt inhibited in her presence.","e2":"Onun yanındayken kendini tutuk (çekingen) hissetti.","e2t":"Inhibition (noun)."},{"w":"inimical","tr":"düşmanca / zararlı / elverişsiz","te":"Adjective","tt":"Sıfat","de":"Tending to obstruct or harm; unfriendly","dt":"Bir şeye zarar veren veya engel olan; düşmanca","e1":"Conditions inimical to development.","e1t":"Gelişime engel (zararlı) koşullar.","e2":"Inimical forces.","e2t":"Düşman güçler."},{"w":"inimitable","tr":"eşsiz / taklit edilemez","te":"Adjective","tt":"Sıfat","de":"So good or unusual as to be impossible to copy; unique","dt":"O kadar iyi veya sıra dışı ki taklit edilmesi imkansız olan","e1":"In his own inimitable style.","e1t":"Kendi eşsiz (taklit edilemez) tarzıyla.","e2":"An inimitable performance.","e2t":"Benzersiz bir performans."},{"w":"iniquitous","tr":"haksız / adaletsiz / çok kötü","te":"Adjective","tt":"Sıfat","de":"Grossly unfair and morally wrong","dt":"Ahlaken yanlış ve son derece adaletsiz","e1":"An iniquitous tax system.","e1t":"Adaletsiz bir vergi sistemi.","e2":"Such iniquitous laws must be changed.","e2t":"Böylesine haksız yasalar değiştirilmelidir."},{"w":"injurious","tr":"zararlı / incitici","te":"Adjective","tt":"Sıfat","de":"Causing or likely to cause damage or harm","dt":"Zarar veren veya vermesi muhtemel olan","e1":"Smoking is injurious to health.","e1t":"Sigara içmek sağlığa zararlıdır.","e2":"Injurious remarks.","e2t":"İncitici (hakaretamiz) sözler."},{"w":"inkling","tr":"ipucu / belirti / hafif bir sezgi","te":"Noun","tt":"İsim","de":"A slight knowledge or suspicion; a hint","dt":"Bir şey hakkında zayıf bir fikir veya şüphe","e1":"I had an inkling that she was unhappy.","e1t":"Onun mutsuz olduğuna dair bir sezgim (ipucum) vardı.","e2":"To give someone an inkling of what is to come.","e2t":"Birine olacaklar hakkında hafif bir ipucu vermek."},{"w":"innuendo","tr":"ima / üstü kapalı laf dokundurma","te":"Noun","tt":"İsim","de":"An allusive or oblique remark or hint, typically a suggestive or disparaging one","dt":"Genellikle imalı, iğneleyici ve nahoş bir hatırlatma","e1":"To make an innuendo about someone's character.","e1t":"Birinin karakteri hakkında imalı (iğneleyici) bir laf etmek.","e2":"A campaign based on rumors and innuendo.","e2t":"Söylentiler ve imalar üzerine kurulu bir kampanya."},{"w":"inopportune","tr":"yersiz / zamansız / uygun olmayan","te":"Adjective","tt":"Sıfat","de":"Coming or happening at a bad time","dt":"Uygun olmayan bir zamanda gerçekleşen","e1":"I'm sorry to call at such an inopportune moment.","e1t":"Böyle zamansız (münasebetsiz) bir anda aradığım için üzgünüm.","e2":"An inopportune arrival.","e2t":"Zamansız geliş. (Not: Opportune"},{"w":"inordinate","tr":"aşırı / ölçüsüz / haddinden fazla","te":"Adjective","tt":"Sıfat","de":"Unusually or disproportionately large; excessive","dt":"Makul sınırların ötesinde olan; çok fazla","e1":"They spent an inordinate amount of time on the project.","e1t":"Proje üzerinde haddinden fazla (aşırı) zaman harcadılar.","e2":"Inordinate demands.","e2t":"Ölçüsüz talepler."},{"w":"insensate","tr":"duyarsız / cansız / akılsızca","te":"Adjective","tt":"Sıfat","de":"Lacking physical sensation; or completely lacking sense or reason","dt":"Fiziksel duyusu olmayan (cansız); veya tamamen akıl dışı","e1":"Insensate rage.","e1t":"Akıl dışı (kör) bir öfke.","e2":"Insensate objects like rocks.","e2t":"Taşlar gibi cansız nesneler."},{"w":"insidious","tr":"sinsi / içten içe yayılan","te":"Adjective","tt":"Sıfat","de":"Proceeding in a gradual, subtle way, but with harmful effects","dt":"Yavaş ve gizlice ilerleyen ancak zararlı etkileri olan","e1":"An insidious disease.","e1t":"Sinsi (belirti göstermeden ilerleyen) bir hastalık.","e2":"The insidious effects of propaganda.","e2t":"Propagandanın sinsi etkileri."},{"w":"insinuate","tr":"ima etmek / sinsi bir şekilde sokulmak / (aklına) sokmak","te":"Verb","tt":"Fiil","de":"Suggest or hint (something bad) in an indirect and unpleasant way; or to slide gradually into","dt":"Kötü bir şeyi dolaylı yoldan ima etmek; veya (bir yere/gruba) sinsi bir şekilde sızmak","e1":"Are you insinuating that I'm dishonest?","e1t":"Dürüst olmadığımı mı ima ediyorsun?","e2":"He managed to insinuate himself into the inner circle.","e2t":"Kendini sinsi bir şekilde iç çevreye kabul ettirmeyi başardı."},{"w":"insipid","tr":"tatsız tuzsuz / yavşak / sıkıcı / yavan","te":"Adjective","tt":"Sıfat","de":"Lacking flavor; or lacking vigor or interest","dt":"Lezzetsiz; veya (kişi/konuşma için) ruhsuz, bayat ve heyecansız","e1":"An insipid soup.","e1t":"Tatsız bir çorba.","e2":"Insipid conversation.","e2t":"Yavan (sıkıcı) konuşma."},{"w":"insolence","tr":"küstahlık / arsızlık / hadsizlik","te":"Noun","tt":"İsim","de":"Rude and disrespectful behavior","dt":"Kaba ve saygısızca tavır","e1":"I won't tolerate such insolence.","e1t":"Böyle bir küstahlığa müsamaha göstermeyeceğim.","e2":"Insolent (adjective).","e2t":"Küstah / Hadsiz."},{"w":"insouciant","tr":"kaygısız / vurdumduymaz / tasasız","te":"Adjective","tt":"Sıfat","de":"Showing a casual lack of concern; indifferent","dt":"Kaygısız, hiçbir şeyi takmayan (rahat)","e1":"An insouciant attitude toward money.","e1t":"Paraya karşı vurdumduymaz bir tavır.","e2":"Insouciance (noun).","e2t":"Kaygısızlık / Vurdumduymazlık."},{"w":"insubordination","tr":"itaatsizlik / dikbaşlılık","te":"Noun","tt":"İsim","de":"Defiance of authority; refusal to obey orders","dt":"Otoriteye karşı gelme; emirlere uymama","e1":"He was fired for insubordination.","e1t":"İtaatsizlikten dolayı işten atıldı.","e2":"Insubordinate (adjective).","e2t":"İtaatsiz."},{"w":"insufferable","tr":"çekilmez / katlanılmaz","te":"Adjective","tt":"Sıfat","de":"Too extreme to bear; intolerable","dt":"Tahammül edilemez derecede kötü","e1":"An insufferable person.","e1t":"Çekilmez (sinir bozucu) birisi.","e2":"The heat was insufferable.","e2t":"Sıcaklık dayanılmazdı."},{"w":"insuperable","tr":"yenilemez / aşılamaz / başa çıkılamaz","te":"Adjective","tt":"Sıfat","de":"(Of a difficulty or obstacle) impossible to overcome","dt":"(Zorluk veya engel için) aşılması imkansız olan","e1":"Insuperable difficulties.","e1t":"Aşılamaz zorluklar.","e2":"An insuperable problem.","e2t":"Başa çıkılamaz bir sorun."},{"w":"insurrection","tr":"ayaklanma / isyan","te":"Noun","tt":"İsim","de":"A violent uprising against an authority or government","dt":"Otoriteye veya hükümete karşı başlatılan şiddetli ayaklanma","e1":"To lead an insurrection.","e1t":"Bir ayaklanmaya liderlik etmek.","e2":"An armed insurrection.","e2t":"Silahlı isyan."},{"w":"intangible","tr":"somut olmayan / elle tutulamaz / manevi","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unable to be touched or grasped; not having physical presence","dt":"Fiziksel varlığı olmayan, elle tutulamaz; veya (vaka için) belirsiz","e1":"Intangible assets (like a brand's reputation).","e1t":"Maddi olmayan (manevi) varlıklar.","e2":"An intangible feeling of dread.","e2t":"Elle tutulamaz (belirsiz) bir korku hissi."},{"w":"intelligentsia","tr":"aydınlar / entelektüeller","te":"Noun","tt":"İsim","de":"Intellectuals or highly educated people as a group, especially as a political force","dt":"Bir toplumdaki eğitimli ve aydın kesim (bir grup olarak)","e1":"The Russian intelligentsia.","e1t":"Rus aydınları.","e2":"To be part of the local intelligentsia.","e2t":"Yerel aydın kesimin bir parçası olmak."},{"w":"intelligible","tr":"anlaşılır / net","te":"Adjective","tt":"Sıfat","de":"Able to be understood; comprehensible","dt":"Anlaşılabilir; açık","e1":"His accent made him barely intelligible.","e1t":"Aksanı yüzünden ne dediği zor anlaşılıyordu.","e2":"An intelligible explanation.","e2t":"Anlaşılır bir açıklama. (Not: Incomprehensible zıttıdır)."},{"w":"intemperate","tr":"ölçüsüz / aşırıya kaçan / sert (tavır)","te":"Adjective","tt":"Sıfat","de":"Having or showing a lack of self","dt":"control; immoderate","e1":"Özdenetimi olmayan; aşırıya kaçan","e1t":"Intemperate language.","e2":"Ölçüsüz (sert) bir dil.","e2t":"Intemperate habits."},{"w":"inter","tr":"gömmek / defnetmek","te":"Verb","tt":"Fiil","de":"Place (a corpse) in a grave or tomb, typically with funeral rites","dt":"Bir cesedi (törenle) mezara koymak","e1":"He was interred in the family plot.","e1t":"Aile mezarlığına defnedildi.","e2":"Interment (noun).","e2t":"Defin işlemi. (Not: Exhume"},{"w":"interdict","tr":"yasaklamak / men etmek / resmi yasak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Prohibit or forbid (something) officially; or an authoritative prohibition","dt":"Resmi olarak bir şeyi yasaklamak; veya men emri","e1":"The court interdicted the sale of the property.","e1t":"Mahkeme mülkün satışını yasakladı.","e2":"To interdict drug trafficking.","e2t":"Uyuşturucu kaçakçılığını önlemek (kesmek)."},{"w":"interim","tr":"geçici / ara dönem / fasıla","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The intervening time; provisional","dt":"İki olay arasındaki süre; geçici","e1":"In the interim.","e1t":"Bu arada / Bu süre zarfında.","e2":"An interim report.","e2t":"Ara rapor (geçici rapor)."},{"w":"interminable","tr":"bitmek bilmeyen / sonsuz gibi görünen","te":"Adjective","tt":"Sıfat","de":"Endless (often used hyperbolically)","dt":"Bitmek bilmeyen (çok uzun süren)","e1":"An interminable meeting.","e1t":"Bitmek bilmeyen (sonsuz gibi gelen) bir toplantı.","e2":"Interminable delays.","e2t":"Sonu gelmez gecikmeler."},{"w":"internecine","tr":"iç (çatışma) / her iki tarafa da zarar veren","te":"Adjective","tt":"Sıfat","de":"Destructive to both sides in a conflict; or relating to conflict within a group","dt":"Bir grup içindeki (içsel) ve her iki tarafı da yıpratan çatışma","e1":"Internecine warfare.","e1t":"İç savaş (iki tarafın da mahvolduğu).","e2":"Internecine struggles within the party.","e2t":"Parti içi (yıpratıcı) mücadeleler."},{"w":"interpolate","tr":"(yazıya vb.) araya ekleme yapmak / (veriden) değer tahmin etmek","te":"Verb","tt":"Fiil","de":"Insert (something of a different nature) into something else; or to estimate values","dt":"Bir metne yeni bölümler eklemek; veya (matematikte) ara değerleri tahmin etmek","e1":"To interpolate a new passage into the text.","e1t":"Metne yeni bir pasaj eklemek.","e2":"Interpolation (noun).","e2t":"Araya ekleme / Ara değer tahmini."},{"w":"interregnum","tr":"fetret devri / hükümdarsız dönem","te":"Noun","tt":"İsim","de":"A period when normal government is suspended, especially between successive reigns or regimes","dt":"Bir hükümdarın veya rejimin sona erip diğerinin başlaması arasındaki boşluk","e1":"The interregnum following the king's death.","e1t":"Kralın ölümünün ardından gelen fetret devri (hükümdarsız dönem).","e2":"","e2t":""},{"w":"interstellar","tr":"yıldızlararası","te":"Adjective","tt":"Sıfat","de":"Situated or occurring between the stars","dt":"Yıldızların arasında bulunan veya gerçekleşen","e1":"Interstellar travel.","e1t":"Yıldızlararası seyahat.","e2":"Interstellar space.","e2t":"Yıldızlararası boşluk."},{"w":"interstice","tr":"aralık / çatlak / küçük boşluk","te":"Noun","tt":"İsim","de":"An intervening space, especially a very small one","dt":"Özellikle çok küçük olan ara boşluk veya yarık","e1":"Sunlight filtered through the interstices of the shutters.","e1t":"Gün ışığı panjurların aralıklarından süzüldü.","e2":"Interstitial (adjective).","e2t":"Hücreler arası / Ara boşluktaki."},{"w":"intransigent","tr":"ödün vermez / uzlaşmaz / dikbaşlı","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Unwilling or refusing to change one's views or to agree about something","dt":"Görüşlerini değiştirmeyi veya uzlaşmayı reddeden","e1":"He remained intransigent despite all the offers.","e1t":"Tüm tekliflere rağmen ödün vermedi (uzlaşmaz kaldı).","e2":"Intransigence (noun).","e2t":"Uzlaşmazlık."},{"w":"intrepid","tr":"korkusuz / gözü pek / yiğit","te":"Adjective","tt":"Sıfat","de":"Fearless; adventurous (often used for rhetorical or humorous effect)","dt":"Hiçbir şeyden korkmayan (cesur)","e1":"An intrepid explorer.","e1t":"Gözü pek bir kaşif.","e2":"Our intrepid reporter.","e2t":"Korkusuz muhabirimiz. (Not: Genellikle olumlu anlamda kullanılır)."},{"w":"intrinsic","tr":"içsel / asli / doğasında olan","te":"Adjective","tt":"Sıfat","de":"Belonging naturally; essential","dt":"Bir şeyin özünde olan (asli)","e1":"Intrinsic value.","e1t":"Asli (öz) değer.","e2":"Small details that are intrinsic to the design.","e2t":"Tasarımın doğasında olan (ayrılmaz) küçük detaylar. (Not: Extrinsic"},{"w":"introspective","tr":"iç gözlemci / kendi iç dünyasına bakan","te":"Adjective","tt":"Sıfat","de":"Characterized by examination of one's own thoughts and feelings","dt":"Kendi duygu ve düşüncelerini inceleyen; içe dönük","e1":"An introspective person.","e1t":"Kendi iç dünyasına bakan (düşünceli) birisi.","e2":"An introspective mood.","e2t":"Kendi üzerine düşünen (içsel) bir ruh hali."},{"w":"intrude","tr":"davetsiz girmek / rahatsız etmek / müdahale etmek","te":"Verb","tt":"Fiil","de":"Put oneself into a place or situation where one is unwelcome or uninvited","dt":"İstenmediği bir yere veya duruma (izinsiz) girmek","e1":"I'm sorry to intrude on your privacy.","e1t":"Özel hayatınıza müdahale ettiğim (izinsiz girdiğim) için üzgünüm.","e2":"To intrude into a conversation.","e2t":"Bir konuşmanın arasına (hadsizce) girmek."},{"w":"inundate","tr":"sel basmak / (bir şeye) boğmak / istila etmek","te":"Verb","tt":"Fiil","de":"Overwhelm someone with things or people to be dealt with; or to flood","dt":"Birini (iş, soru vb.) ile boğmak; veya su basmak","e1":"We were inundated with complaints.","e1t":"Şikayet yağmuruna tutulduk (şikayete boğulduk).","e2":"The islands were inundated by the tide.","e2t":"Adalar gelgit suları altında kaldı."},{"w":"inure","tr":"alıştırmak / (zorluğa) dayanıklı kılmak","te":"Verb","tt":"Fiil","de":"Accustom someone to something, especially something unpleasant","dt":"Birini (genellikle nahoş bir şeye) alıştırmak veya duyarsızlaştırmak","e1":"To be inured to hardship.","e1t":"Zorluklara alışık (dirençli) olmak.","e2":"After years of war, they became inured to violence.","e2t":"Yıllarca süren savaştan sonra şiddete karşı duyarsızlaştılar."},{"w":"inveigh","tr":"şiddetle eleştirmek / ateş püskürmek","te":"Verb","tt":"Fiil","de":"Speak or write about something with great hostility","dt":"Bir şeye karşı büyük bir nefretle konuşmak veya yazmak","e1":"He inveighed against the new taxes.","e1t":"Yeni vergilere karşı ateş püskürdü.","e2":"To inveigh against corruption.","e2t":"Yolsuzluğa karşı şiddetle sesini yükseltmek."},{"w":"inveigle","tr":"kandırarak yaptırmak / ayartmak / kurnazlıkla elde etmek","te":"Verb","tt":"Fiil","de":"Persuade someone to do something by means of deception or flattery","dt":"Birini aldatarak veya dalkavuklukla bir şeye razı etmek","e1":"He inveigled his way into the meeting.","e1t":"Kurnazlıkla kendini toplantıya kabul ettirdi.","e2":"To inveigle someone into a deal.","e2t":"Birini kandırarak bir anlaşmaya dahil etmek."},{"w":"invert","tr":"ters çevirmek / evirmek","te":"Verb","tt":"Fiil","de":"Put upside down or in the opposite position, order, or arrangement","dt":"Baş aşağı çevirmek veya tersine çevirmek","e1":"To invert a glass.","e1t":"Bir bardağı ters çevirmek.","e2":"Inverted commas (quotation marks).","e2t":"Tırnak işaretleri."},{"w":"invertebrate","tr":"omurgasız (hayvan)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"An animal lacking a backbone","dt":"Omurgası (sırt kemiği) olmayan hayvan","e1":"Insects and snails are invertebrates.","e1t":"Böcekler ve salyangozlar omurgasızdır.","e2":"Invertebrate zoology.","e2t":"Omurgasızlar zoolojisi. (Not: Vertebrate"},{"w":"investiture","tr":"törenle göreve başlama / atama töreni","te":"Noun","tt":"İsim","de":"The action of formally investing a person with honors or rank","dt":"Birine resmi olarak bir rütbe veya unvan verilmesi töreni","e1":"The investiture of the new bishop.","e1t":"Yeni piskoposun göreve başlama töreni.","e2":"An investiture ceremony at the palace.","e2t":"Saraydaki atama (unvan verme) töreni."},{"w":"inveterate","tr":"kökleşmiş / alışkanlık edinmiş / iflah olmaz","te":"Adjective","tt":"Sıfat","de":"Having a particular habit, activity, or interest that is long","dt":"established and unlikely to change","e1":"Uzun süredir devam eden ve değişmesi zor olan (alışkanlık/kişi)","e1t":"An inveterate liar.","e2":"İflah olmaz (müzmin) bir yalancı.","e2t":"Inveterate hostility."},{"w":"invidious","tr":"kıskançlık uyandıran / haksız / nahoş","te":"Adjective","tt":"Sıfat","de":"(Of a task or situation) likely to arouse or incur resentment or anger in others","dt":"(Görev veya durum için) başkalarında kıskançlık veya öfke uyandırması muhtemel olan","e1":"To be in an invidious position.","e1t":"Nahoş (veya haksız görünen) bir durumda olmak.","e2":"Invidious comparisons.","e2t":"(İnsanları birbirine düşüren) haksız karşılaştırmalar."},{"w":"inviolable","tr":"kutsal / dokunulmaz / bozulamaz","te":"Adjective","tt":"Sıfat","de":"Never to be broken, infringed, or dishonored","dt":"Hiçbir şekilde çiğnenemez veya ihlal edilemez olan","e1":"Inviolable human rights.","e1t":"Dokunulmaz insan hakları.","e2":"An inviolable oath.","e2t":"Bozulamaz (kutsal) bir yemin."},{"w":"invocation","tr":"dua / yardım çağırma / (yasaya vb.) başvurma","te":"Noun","tt":"İsim","de":"The action of invoking someone or something for assistance or as an authority","dt":"Yardım için (Tanrı'ya vb.) yakarma; veya bir kanunu dayanak olarak gösterme","e1":"An invocation for peace.","e1t":"Barış için bir yakarış (dua).","e2":"The invocation of a treaty.","e2t":"Bir antlaşmaya dayanma (başvurma)."},{"w":"involuted / involute","tr":"karmaşık / iç içe geçmiş / sarmal","te":"Adjective","tt":"Sıfat","de":"Complicated; abstruse; or curled spirally inwards","dt":"Karmaşık; anlaşılması güç; veya (biyolojide) içe kıvrılmış","e1":"An involuted argument.","e1t":"Karmaşık (içinden çıkılması zor) bir iddia.","e2":"Involute leaves.","e2t":"İçe doğru kıvrılmış yapraklar."},{"w":"invulnerable","tr":"yaralanamaz / zarar verilemez / zayıf noktası olmayan","te":"Adjective","tt":"Sıfat","de":"Impossible to harm or damage","dt":"Zarar verilmesi veya alt edilmesi imkansız olan","e1":"The fort was invulnerable to attack.","e1t":"Kale saldırılara karşı korunaktı (zarar verilemezdi).","e2":"He felt invulnerable behind his desk.","e2t":"Masasının arkasında kendini güvende (sarsılmaz) hissediyordu. (Not: Vulnerable"},{"w":"iota","tr":"zerre / gıdım / iyota (Yunan harfi)","te":"Noun","tt":"İsim","de":"An extremely small amount; or the ninth letter of the Greek alphabet","dt":"Çok küçük miktar (zerre); veya Yunan alfabesinin 9. harfi","e1":"It doesn't make an iota of difference.","e1t":"Zerre kadar fark etmez.","e2":"There isn't an iota of truth in it.","e2t":"İçinde bir gıdım bile doğruluk yok."},{"w":"irascible","tr":"çabuk öfkelenen / barut gibi / asabi","te":"Adjective","tt":"Sıfat","de":"Having or showing a tendency to be easily angered","dt":"Çok kolay sinirlenen; asabi","e1":"An irascible old man.","e1t":"Huysuz (çabuk parlayan) bir ihtiyar.","e2":"He has an irascible temperament.","e2t":"Asabi bir mizacı var."},{"w":"iridescent","tr":"yanardöner / gökkuşağı gibi renkli","te":"Adjective","tt":"Sıfat","de":"Showing luminous colors that seem to change when seen from different angles","dt":"Farklı açılardan bakıldığında değişen parlak renklere sahip olan","e1":"Iridescent bubbles.","e1t":"Yanardöner sabun köpükleri.","e2":"The iridescent feathers of a peacock.","e2t":"Bir tavus kuşunun yanardöner tüyleri."},{"w":"irksome","tr":"can sıkıcı / bıktırıcı / yorucu","te":"Adjective","tt":"Sıfat","de":"Irritating; annoying","dt":"Sinir bozucu veya bıktırıcı","e1":"An irksome task.","e1t":"Bıktırıcı (sıkıcı) bir iş.","e2":"It was irksome to have to wait.","e2t":"Beklemek zorunda kalmak can sıkıcıydı."},{"w":"ironic / ironical","tr":"ironik / alaycı / beklenenin tersi olan","te":"Adjective","tt":"Sıfat","de":"Using or characterized by irony; or happening in the opposite way to what is expected","dt":"İroni içeren; veya beklenenin tam tersi gerçekleşen (alaycı bir durum)","e1":"It's ironic that the fire station burned down.","e1t":"İtfaiye istasyonunun yanması ironiktir.","e2":"An ironic smile.","e2t":"Alaycı bir gülümseme."},{"w":"irradiate","tr":"ışınlamak / aydınlatmak / (radyasyona) maruz bırakmak","te":"Verb","tt":"Fiil","de":"Expose to radiation; or to illuminate","dt":"Radyasyona maruz bırakmak; veya (mecazi) aydınlatmak/parlatmak","e1":"Irradiated food.","e1t":"Işınlanmış (mikroplardan arındırılmış) gıda.","e2":"Her face was irradiated with joy.","e2t":"Yüzü neşeyle aydınlandı (parladı)."},{"w":"irreconcilable","tr":"uzlaştırılamaz / bağdaşmaz / giderilemez","te":"Adjective","tt":"Sıfat","de":"(Of ideas, facts, or statements) representing findings or points of view that are so different from each other that they cannot be made compatible","dt":"Birbiriyle uyumlu hale getirilmesi imkansız olan (zıt)","e1":"Irreconcilable differences (often a cause for divorce).","e1t":"Giderilemez (uzlaştırılamaz) fikir ayrılıkları.","e2":"Two irreconcilable enemies.","e2t":"Asla barışmayacak (uzlaşmaz) iki düşman."},{"w":"irredeemable","tr":"kurtarılamaz / düzelmez / telafi edilemez","te":"Adjective","tt":"Sıfat","de":"Not able to be saved, improved, or corrected","dt":"Kurtarılması veya düzeltilmesi imkansız olan","e1":"An irredeemable mistake.","e1t":"Telafisi mümkün olmayan bir hata.","e2":"He is an irredeemable scoundrel.","e2t":"O, iflah olmaz (düzelmez) bir alçaktır."},{"w":"irrefutable","tr":"aksisi ispatlanamaz / kesin / tartışılamaz","te":"Adjective","tt":"Sıfat","de":"Impossible to deny or disprove","dt":"Yalanlanması veya aksinin kanıtlanması imkansız olan","e1":"Irrefutable evidence.","e1t":"Aksisi ispatlanamaz (kesin) kanıt.","e2":"An irrefutable argument.","e2t":"Tartışılamaz bir iddia."},{"w":"irremediable","tr":"çaresiz / iyileştirilemez / telafisiz","te":"Adjective","tt":"Sıfat","de":"Impossible to cure or put right","dt":"İyileştirilmesi veya düzeltilmesi imkansız olan","e1":"Irremediable damage.","e1t":"Telafi edilemez (düzeltilemez) hasar.","e2":"An irremediable disease.","e2t":"Çaresi olmayan hastalık."},{"w":"irrepressible","tr":"zapt edilemez / önlenemez / ele avuca sığmaz","te":"Adjective","tt":"Sıfat","de":"Not able to be controlled or restrained","dt":"Bastırılması veya kontrol edilmesi imkansız olan","e1":"An irrepressible urge to laugh.","e1t":"Önlenemez bir gülme arzusu.","e2":"Irrepressible energy.","e2t":"Ele avuca sığmaz (zapt edilemez) enerji."},{"w":"irreproachable","tr":"kusursuz / sitem edilemez / tertemiz","te":"Adjective","tt":"Sıfat","de":"Beyond criticism; faultless","dt":"Eleştirilemeyecek kadar iyi; lekesiz","e1":"Her conduct has been irreproachable.","e1t":"Davranışları kusursuzdur (asla eleştirilemez).","e2":"An irreproachable reputation.","e2t":"Tertemiz (lekesiz) bir itibar."},{"w":"irresolute","tr":"kararsız / tereddütlü","te":"Adjective","tt":"Sıfat","de":"Showing or feeling hesitancy; uncertain","dt":"Ne yapacağını bilemeyen, kararsız","e1":"He stood irresolute for a moment.","e1t":"Bir an kararsızca (tereddütle) bekledi.","e2":"An irresolute leader.","e2t":"Kararsız bir lider. (Not: Resolute"},{"w":"irretrievable","tr":"geri getirilemez / telafi edilemez / ebediyen kayıp","te":"Adjective","tt":"Sıfat","de":"Not able to be retrieved or put right","dt":"Geri kazanılması veya düzeltilmesi imkansız olan","e1":"Irretrievable loss of data.","e1t":"Verilerin geri getirilemez şekilde kaybı.","e2":"The situation is irretrievable.","e2t":"Durum artık düzeltilemez."},{"w":"irreverence","tr":"saygısızlık / hürmetsizlik","te":"Noun","tt":"İsim","de":"A lack of respect for people or things that are generally taken seriously","dt":"Genelde ciddiye alınan kişi veya değerlere karşı saygı eksikliği","e1":"A tone of irreverence.","e1t":"Alaycı (saygısız) bir ton.","e2":"Irreverent (adjective).","e2t":"Saygısız / Hürmetsiz."},{"w":"irrevocable","tr":"geri dönülemez / feshedilemez / kesin","te":"Adjective","tt":"Sıfat","de":"Not able to be changed, reversed, or recovered; final","dt":"Değiştirilmesi, geri alınması veya iptal edilmesi imkansız olan","e1":"An irrevocable decision.","e1t":"Geri dönülemez (kesin) bir karar.","e2":"Irrevocable letter of credit (finance).","e2t":"Gayrikabili rücu (cayılmaz) akreditif."},{"w":"isotope","tr":"izotop","te":"Noun","tt":"İsim","de":"Each of two or more forms of the same element that contain equal numbers of protons but different numbers of neutrons","dt":"Aynı elementin, proton sayısı aynı ancak nötron sayısı farklı olan formları","e1":"Radioactive isotopes.","e1t":"Radyoaktif izotoplar.","e2":"Carbon","e2t":"14 is an isotope of carbon used in dating."},{"w":"isthmus","tr":"kıstak / berzah","te":"Noun","tt":"İsim","de":"A narrow strip of land with sea on either side, forming a link between two larger areas of land","dt":"İki büyük kara parçasını birbirine bağlayan, iki yanı deniz olan dar kara şeridi","e1":"The Isthmus of Panama.","e1t":"Panama Kıstağı.","e2":"A narrow isthmus connecting the peninsula to the mainland.","e2t":"Yarımadayı ana karaya bağlayan dar bir kıstak."},{"w":"itinerant","tr":"gezgin / seyyar","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Traveling from place to place","dt":"İş veya görev gereği yer yer gezen","e1":"Itinerant laborers.","e1t":"Mevsimlik (gezgin) işçiler.","e2":"An itinerant musician.","e2t":"Seyyar bir müzisyen."},{"w":"jabber","tr":"hızlı ve anlaşılmaz konuşmak / gevezelik etmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Talk rapidly and excitedly but with little sense","dt":"Hızlı, heyecanlı ama anlamsız şekilde (lak lak ederek) konuşmak","e1":"Stop jabbering and speak clearly!","e1t":"Gevezeliği (anlamsız konuşmayı) bırak ve net konuş!","e2":"A constant jabber of voices.","e2t":"Sürekli bir ses kalabalığı (lak lak)."},{"w":"jaunty","tr":"neşeli / şen şakrak / havalı","te":"Adjective","tt":"Sıfat","de":"Having or expressing a lively, cheerful, and self","dt":"confident manner","e1":"Kendinden emin, canlı ve neşeli","e1t":"A jaunty walk.","e2":"Havalı (neşeli) bir yürüyüş.","e2t":"To wear a hat at a jaunty angle."},{"w":"jeopardize / jeopardise","tr":"tehlikeye atmak / riske atmak","te":"Verb","tt":"Fiil","de":"Put (someone or something) into a situation in which there is a danger of loss, harm, or failure","dt":"Birini veya bir şeyi tehlikeye veya riskli bir duruma sokmak","e1":"His behavior could jeopardize his career.","e1t":"Davranışları kariyerini tehlikeye atabilir.","e2":"Don't jeopardize the peace process.","e2t":"Barış sürecini riske atma."},{"w":"jettison","tr":"(yükü) uçaktan/gemiden atmak / vazgeçmek","te":"Verb","tt":"Fiil","de":"Throw or drop (something) from an aircraft or ship; or to abandon something no longer wanted","dt":"(Acil durumda) gemi veya uçaktan yük boşaltmak; veya (plan/fikir) terk etmek","e1":"The pilot decided to jettison the fuel.","e1t":"Pilot yakıtı boşaltmaya (atıp kurtulmaya) karar verdi.","e2":"To jettison an old plan.","e2t":"Eski bir plandan vazgeçmek."},{"w":"jocose","tr":"şakacı / esprili / nüktedan","te":"Adjective","tt":"Sıfat","de":"Playful or humorous","dt":"Şaka yapmayı seven; neşeli","e1":"A jocose remark.","e1t":"Şakacı (nükteli) bir yorum.","e2":"In a jocose mood.","e2t":"Şakacı (neşeli) bir ruh halinde."},{"w":"jocular","tr":"şakacı / komik","te":"Adjective","tt":"Sıfat","de":"Fond of or characterized by joking; humorous or playful","dt":"Şaka yapmaya meyilli veya şaka içeren","e1":"A jocular comment.","e1t":"Esprili bir yorum.","e2":"He was in a jocular mood.","e2t":"Şakacı (keyifli) bir moddaydı."},{"w":"jocund","tr":"şen / neşeli / hayat dolu","te":"Adjective","tt":"Sıfat","de":"Cheerful and lighthearted","dt":"Neşeli ve tasasız","e1":"A jocund company.","e1t":"Şen (neşeli) bir topluluk.","e2":"(Not: Daha çok edebi bir kullanımdır).","e2t":""},{"w":"jostle","tr":"itip kakmak / (kalabalıkta) dirsek atmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Push, elbow, or bump against (someone) roughly, typically in a crowd","dt":"Özellikle kalabalıkta birini kaba bir şekilde itmek veya çarpmak","e1":"People were jostling to get a better view.","e1t":"İnsanlar daha iyi görebilmek için birbirlerini itip kakıyorlardı.","e2":"To be jostled in the street.","e2t":"Sokakta itilip kakılmak."},{"w":"jovial","tr":"neşeli / cana yakın / şen","te":"Adjective","tt":"Sıfat","de":"Cheerful and friendly","dt":"Çok neşeli ve dost canlısı","e1":"A jovial host.","e1t":"Cana yakın (şen) bir ev sahibi.","e2":"His jovial laugh.","e2t":"Onun neşeli kahkahası."},{"w":"jubilation","tr":"büyük sevinç / coşku / zafer sarhoşluğu","te":"Noun","tt":"İsim","de":"A feeling of great happiness and triumph","dt":"Büyük bir başarı veya sevinç sonrası yaşanan coşku","e1":"There was great jubilation when the war ended.","e1t":"Savaş bittiğinde büyük bir coşku (sevinç) yaşandı.","e2":"Jubilant (adjective).","e2t":"Coşkulu / Çok sevinçli."},{"w":"juncture","tr":"kritik an / kavşak / dönüm noktası","te":"Noun","tt":"İsim","de":"A particular point in events or time; or a place where things join","dt":"Olayların akışındaki belirli (genellikle kritik) bir an; veya birleşme noktası","e1":"At this juncture, we must make a decision.","e1t":"Bu kritik aşamada (anda) bir karar vermeliyiz.","e2":"A critical juncture.","e2t":"Dönüm noktası."},{"w":"junket","tr":"(devlet kesesinden) ziyafet / gezi / bir tür tatlı","te":"Noun/Verb","tt":"İsim/Fiil","de":"An extravagant trip or celebration, especially one enjoyed by a government official at public expense","dt":"Özellikle kamu görevlilerinin halkın parasıyla çıktığı lüks gezi veya ziyafet","e1":"A political junket to Hawaii.","e1t":"Hawaii'ye yapılan (kamu kaynaklı) siyasi gezi.","e2":"","e2t":""},{"w":"junta","tr":"cunta / askeri yönetim","te":"Noun","tt":"İsim","de":"A military or political group that rules a country after taking power by force","dt":"Gücü zorla ele geçirdikten sonra ülkeyi yöneten askeri veya siyasi grup","e1":"The military junta seized power in a coup.","e1t":"Askeri cunta darbeyle yönetime el koydu.","e2":"","e2t":""},{"w":"juxtapose","tr":"yan yana getirmek (karşılaştırmak için)","te":"Verb","tt":"Fiil","de":"Place or deal with close together for contrasting effect","dt":"Zıtlık yaratmak veya karşılaştırmak amacıyla iki şeyi yan yana koymak","e1":"The exhibit juxtaposes traditional and modern art.","e1t":"Sergi, geleneksel ve modern sanatı yan yana getiriyor.","e2":"Juxtaposition (noun).","e2t":"Yan yana getirme (karşıtlık için)."},{"w":"ken","tr":"bilgi alanı / görüş / tanımak (İskoçya)","te":"Noun/Verb","tt":"İsim/Fiil","de":"One's range of knowledge or sight","dt":"Birinin bilgi veya görüş alanı","e1":"Such abstract theories are beyond my ken.","e1t":"Bu tür soyut teoriler benim bilgi alanımın (anlayışımın) dışındadır.","e2":"Beyond human ken.","e2t":"İnsan bilgisinin ötesinde."},{"w":"killjoy","tr":"oyunbozan / neşe kaçıran kimse","te":"Noun","tt":"Isim","de":"A person who deliberately spoils the enjoyment of others","dt":"Başkalarının eğlencesini kasten bozan (mızmız) kişi","e1":"Don't be such a killjoy!","e1t":"Bu kadar oyunbozan olma!","e2":"(Not: Wet blanket ile benzerdir).","e2t":""},{"w":"kindle","tr":"yakmak / ateşlemek / (duygu) uyandırmak","te":"Verb","tt":"Fiil","de":"Light or set on fire; or arouse or inspire (an emotion)","dt":"Ateş yakmak; veya (duygu, ilgi vb.) uyandırmak/başlatmak","e1":"To kindle a fire.","e1t":"Ateş yakmak.","e2":"The teacher helped to kindle his interest in science.","e2t":"Öğretmen onun bilime olan ilgisini uyandırmaya yardımcı oldu."},{"w":"kismet","tr":"kısmet / kader / nasip","te":"Noun","tt":"İsim","de":"Destiny; fate","dt":"Yazgı; kader (Türkçeden İngilizceye geçmiştir)","e1":"It was kismet that we met.","e1t":"Karşılaşmamız bir kısmetti (kaderdi).","e2":"","e2t":""},{"w":"kleptomaniac","tr":"kleptoman / çalma hastası","te":"Noun","tt":"İsim","de":"A person who has an irresistible tendency to steal","dt":"Çalma dürtüsüne engel olamayan (hasta) kişi","e1":"He was diagnosed as a kleptomaniac.","e1t":"Kendisine kleptomani teşhisi kondu.","e2":"Kleptomania (noun).","e2t":"Çalma hastalığı."},{"w":"knave","tr":"düzenbaz / hilekar / vale (iskambil)","te":"Noun","tt":"İsim","de":"A dishonest or unscrupulous man; or the jack in playing cards","dt":"Sahtekar (alçak) adam; veya iskambil oyunundaki vale","e1":"He is a cunning knave.","e1t":"O, kurnaz bir düzenbazdır.","e2":"Knavish (adjective).","e2t":"Sahtekarca."},{"w":"knell","tr":"cenaze çanı sesi / uğursuz belirti","te":"Noun/Verb","tt":"İsim/Fiil","de":"The sound of a bell, especially when rung solemnly for a death or funeral","dt":"Özellikle ölüm veya cenaze için çalınan çan sesi; veya bir sonun habercisi","e1":"The knell of the old regime.","e1t":"Eski rejimin sonunun habercisi (çanı).","e2":"To sound the death knell.","e2t":"Bir şeyin sonunun geldiğini ilan etmek."},{"w":"knoll","tr":"tepecik / tümsek","te":"Noun","tt":"İsim","de":"A small natural hill","dt":"Küçük, doğal tepe","e1":"A grassy knoll.","e1t":"Otlarla kaplı tepecik.","e2":"","e2t":""},{"w":"labile","tr":"değişken / kararsız (kimya/ruh hali)","te":"Adjective","tt":"Sıfat","de":"Liable to change; easily altered","dt":"Değişime meyilli; kolayca değişebilen","e1":"Labile emotions.","e1t":"Değişken (istikrarsız) duygular.","e2":"Thermally labile (heat","e2t":"sensitive)."},{"w":"lacerate","tr":"yırtmak / parçalamak / (kalbini) yaralamak","te":"Verb","tt":"Fiil","de":"Tear or make deep cuts in (flesh or skin); or to distress (someone) deeply","dt":"(Eti veya deriyi) derinden kesmek veya yırtmak; veya birini manen çok yaralamak","e1":"The broken glass lacerated his arm.","e1t":"Kırık cam kolunu parçaladı (derin kesikler açtı).","e2":"Lacerating criticism.","e2t":"İnsanın içini acıtan (yaralayıcı) eleştiri."},{"w":"lachrymose","tr":"hüzünlü / gözü yaşlı / ağlak","te":"Adjective","tt":"Sıfat","de":"Tearful or given to weeping; inducing tears","dt":"Gözü yaşlı; veya gözyaşı döktüren (hüzünlü)","e1":"A lachrymose drama.","e1t":"Ağlak (dokunaklı) bir drama.","e2":"She was in a lachrymose mood.","e2t":"Gözü yaşlı (hüzünlü) bir ruh halindeydi."},{"w":"lackey","tr":"uşak / dalkavuk / ayak işlerine bakan","te":"Noun","tt":"İsim","de":"A person who is obsequiously willing to obey or serve another person","dt":"Birine kölece itaat eden (dalkavuk) yardımcı/uşak","e1":"He is just a lackey of the governor.","e1t":"O sadece valinin bir uşağıdır (emir kuludur).","e2":"","e2t":""},{"w":"laconic","tr":"az ve öz / kısa ve öz / lakonik","te":"Adjective","tt":"Sıfat","de":"(Of a person, speech, or style of writing) using very few words","dt":"Çok az kelime kullanan (öz konuşan)","e1":"A laconic reply.","e1t":"Kısa ve öz bir cevap.","e2":"His laconic style of speaking.","e2t":"Onun az ve öz konuşma tarzı. (Not: İsmini az konuşmalarıyla bilinen Laconialılardan"},{"w":"lagoon","tr":"lagün / deniz kulağı","te":"Noun","tt":"İsim","de":"A stretch of salt water separated from the sea by a low sandbank or coral reef","dt":"Denizden bir kumsal veya mercan kayalığıyla ayrılmış sığ tuzlu su birikintisi","e1":"A tropical lagoon.","e1t":"Tropikal bir lagün.","e2":"The blue water of the lagoon.","e2t":"Lagünün mavi suyu."},{"w":"laity","tr":"ruhban sınıfından olmayanlar / meslekten olmayanlar / halk","te":"Noun","tt":"İsim","de":"Lay people, as distinct from the clergy; or ordinary people as distinct from professionals","dt":"Din adamı olmayan halk; veya (mecazi) bir konunun uzmanı olmayan kitle","e1":"A book written for the laity.","e1t":"Uzman olmayanlar (halk) için yazılmış bir kitap.","e2":"Layman (noun).","e2t":"Sıradan kişi / Uzman olmayan."},{"w":"lambaste / lambast","tr":"şiddetle eleştirmek / haşlamak / dövmek","te":"Verb","tt":"Fiil","de":"Criticize (someone or something) harshly","dt":"Birini veya bir şeyi çok sert bir dille eleştirmek (yerden yere vurmak)","e1":"The critics lambasted his new movie.","e1t":"Eleştirmenler onun yeni filmini yerden yere vurdu.","e2":"","e2t":""},{"w":"lank","tr":"ince uzun / düz ve cansız (saç)","te":"Adjective","tt":"Sıfat","de":"(Of hair) long, limp, and straight; or (of a person) tall and thin","dt":"(Saç için) uzun ve sönük; veya (kişi için) ince uzun (cılız)","e1":"Lank greasy hair.","e1t":"Yağlı ve sönük saçlar.","e2":"A lank youth.","e2t":"İnce uzun (çırpı gibi) bir genç."},{"w":"larder","tr":"kiler / yemek odası","te":"Noun","tt":"İsim","de":"A room or large cupboard for storing food","dt":"Yiyecek saklanan oda veya büyük dolap (kiler)","e1":"A well","e1t":"stocked larder.","e2":"Erzak dolu bir kiler.","e2t":""},{"w":"laxative","tr":"laksatif / müshil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"(Of a drug or medicine) tending to stimulate or facilitate evacuation of the bowels","dt":"Bağırsakları çalıştıran ve boşaltımı kolaylaştıran (ilaç)","e1":"To take a laxative.","e1t":"Müshil içmek.","e2":"Laxative effect.","e2t":"Bağırsak yumuşatıcı etki."},{"w":"leaven","tr":"maya / mayalamak / (etkisini) hafifletmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A substance, typically yeast, that is used in dough to make it rise; or a pervasive influence that modifies something","dt":"Maya; veya (mecazi) bir şeyi daha canlı veya hafif kılan etki","e1":"To leaven bread.","e1t":"Ekmeği mayalamak.","e2":"His humor helped to leaven the serious discussion.","e2t":"Mizahı, ciddi tartışmayı biraz olsun hafifletmeye (neşelendirmeye) yardımcı oldu."},{"w":"lechery","tr":"şehvet düşkünlüğü / azgınlık","te":"Noun","tt":"İsim","de":"Excessive or offensive sexual desire; lustfulness","dt":"Aşırı veya rahatsız edici cinsel arzu","e1":"He was known for his lechery.","e1t":"Şehvet düşkünlüğü ile bilinirdi.","e2":"Lecherous (adjective).","e2t":"Şehvet düşkünü / Azgın."},{"w":"lectern","tr":"nota sehpası / kürsü (üzerinde kitap duran)","te":"Noun","tt":"İsim","de":"A tall stand with a sloping top to hold a book or notes, from which someone, typically a preacher or lecturer, can read while standing up","dt":"Konuşmacının notlarını koyduğu eğimli kürsü veya sehpa","e1":"He stood behind the lectern.","e1t":"Kürsünün arkasına geçti.","e2":"","e2t":""},{"w":"legerdemain","tr":"el çabukluğu / hokkabazlık / hile","te":"Noun","tt":"İsim","de":"Skillful use of one's hands when performing conjuring tricks; or deception","dt":"İlizyonistlikteki el çabukluğu; veya (mecazi) hilekarlık/göz boyama","e1":"Political legerdemain.","e1t":"Siyasi göz boyama (hile).","e2":"A piece of legerdemain.","e2t":"Bir el çabukluğu marifeti."},{"w":"leniency / lenience","tr":"müsamaha / yumuşaklık / merhamet","te":"Noun","tt":"İsim","de":"The quality of being more merciful or tolerant than expected; clemency","dt":"Beklenenden daha merhametli veya hoşgörülü olma durumu","e1":"The judge showed leniency because of his age.","e1t":"Yaşından dolayı yargıç müsamaha (merhamet) gösterdi.","e2":"Lenient (adjective).","e2t":"Yumuşak / Müsamahakar."},{"w":"leonine","tr":"aslan gibi / aslanla ilgili","te":"Adjective","tt":"Sıfat","de":"Of or resembling a lion or lions","dt":"Aslana benzeyen veya aslanla ilgili","e1":"A leonine mane of hair.","e1t":"Aslan yelesi gibi gür saçlar.","e2":"Leonine features.","e2t":"Aslanı andıran (heybetli) yüz hatları."},{"w":"leper","tr":"cüzzamlı / toplumdan dışlanmış kişi","te":"Noun","tt":"İsim","de":"A person suffering from leprosy; or a person who is avoided by others","dt":"Cüzzam hastası; veya (mecazi) herkesin kaçtığı (dışlanmış) kişi","e1":"He was treated like a social leper.","e1t":"Toplumdan dışlanmış (parya) biri gibi muamele gördü.","e2":"Leprosy (noun).","e2t":"Cüzzam."},{"w":"leprosy","tr":"cüzzam (Hansen hastalığı)","te":"Noun","tt":"İsim","de":"A contagious disease that affects the skin, mucous membranes, and nerves","dt":"Cilt ve sinirleri etkileyen bulaşıcı bir hastalık","e1":"A victim of leprosy.","e1t":"Cüzzam kurbanı.","e2":"Leprous (adjective).","e2t":"Cüzzamlı."},{"w":"lesion","tr":"lezyon / doku bozukluğu / yara","te":"Noun","tt":"İsim","de":"A region in an organ or tissue which has suffered damage through injury or disease","dt":"Yaralanma veya hastalık sonucu organda oluşan doku hasarı","e1":"Skin lesions.","e1t":"Cilt lezyonları (bozuklukları).","e2":"A brain lesion.","e2t":"Beyin dokusu hasarı."},{"w":"lethargy","tr":"uyuşukluk / halsizlik / uykulu hal","te":"Noun","tt":"İsim","de":"A lack of energy and enthusiasm","dt":"Enerji ve heves eksikliği; rehavet","e1":"To fall into a state of lethargy.","e1t":"Uyuşukluk (rehavet) içine düşmek.","e2":"Lethargic (adjective).","e2t":"Uyuşuk."},{"w":"levitate","tr":"havaya yükselmek (sihirle/fizikle)","te":"Verb","tt":"Fiil","de":"Rise or cause to rise and hover in the air, especially by means of supernatural or physical force","dt":"(Özellikle doğaüstü veya manyetik güçle) havada asılı kalmak veya yükselmek","e1":"The magician seemed to levitate.","e1t":"Sihirbaz havada yükseliyor gibi göründü.","e2":"Magnetic levitation (Maglev) trains.","e2t":"Manyetik raylı (havada giden) trenler."},{"w":"lexicographer","tr":"sözlük yazarı","te":"Noun","tt":"İsim","de":"A person who compiles dictionaries","dt":"Sözlük hazırlayan (derleyen) kişi","e1":"Samuel Johnson was a famous lexicographer.","e1t":"Samuel Johnson ünlü bir sözlük yazarıydı.","e2":"Lexicography (noun).","e2t":"Sözlükçülük."},{"w":"libido","tr":"libido / cinsel dürtü","te":"Noun","tt":"İsim","de":"Sexual desire","dt":"Cinsel arzu veya enerji","e1":"To have a high libido.","e1t":"Yüksek libidoya (cinsel dürtüye) sahip olmak.","e2":"Psychological factors affecting the libido.","e2t":"Libidoyu etkileyen psikolojik faktörler."},{"w":"libretto","tr":"libretto / opera metni","te":"Noun","tt":"İsim","de":"The text of an opera or other long vocal work","dt":"Bir operanın veya müzikal eserin metni","e1":"To write a libretto for a new opera.","e1t":"Yeni bir opera için libretto yazmak.","e2":"Librettist (noun).","e2t":"Libretto yazarı."},{"w":"lien","tr":"rehin / hapis hakkı","te":"Noun","tt":"İsim","de":"A right to keep possession of property belonging to another person until a debt owed by that person is discharged","dt":"Borç ödenene kadar başkasının malına el koyma (rehin) hakkı","e1":"To place a lien on a property.","e1t":"Bir mülk üzerine rehin (ipotek benzeri hak) koymak.","e2":"","e2t":""},{"w":"ligneous","tr":"odunsu / tahta gibi","te":"Adjective","tt":"Sıfat","de":"Resembling, consisting of, or characteristic of wood","dt":"Odunsu; tahtadan oluşan","e1":"Ligneous plants.","e1t":"Odunsu bitkiler.","e2":"The ligneous texture of the stem.","e2t":"Gövdenin odunsu dokusu."},{"w":"lilliputian","tr":"minnacık / cüce / önemsiz","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Trivial or very small","dt":"Çok küçük veya önemsiz","e1":"A lilliputian village.","e1t":"Küçücük bir köy.","e2":"(Not: İsim babası Gulliver'in Gezileri'ndeki Lilliput cüceleridir).","e2t":""},{"w":"limbo","tr":"belirsizlik / arada kalma / araf","te":"Noun","tt":"İsim","de":"An uncertain period of awaiting a decision or resolution; or (in religion) a place between heaven and hell","dt":"Kararın beklendiği belirsiz süreç (boşlukta kalma); veya (dini) araf","e1":"The project is in limbo until we get funding.","e1t":"Ödenek alana kadar proje belirsizlik içinde (askıda).","e2":"To be left in limbo.","e2t":"Arada (boşlukta) bırakılmak."},{"w":"liminal","tr":"eşik / geçiş aşamasında olan","te":"Adjective","tt":"Sıfat","de":"Relating to a transitional or initial stage of a process; occupying a position at, or on both sides of, a boundary or threshold","dt":"Bir sürecin geçiş veya eşik aşamasıyla ilgili","e1":"A liminal space (like a hallway or waiting room).","e1t":"Eşik (geçiş) alanı.","e2":"The liminal state between childhood and adulthood.","e2t":"Çocukluk ile yetişkinlik arasındaki o geçiş evresi."},{"w":"limn","tr":"çizmek / betimlemek / aydınlatmak","te":"Verb","tt":"Fiil","de":"Depict or describe in paintings or words","dt":"Resimle veya kelimelerle betimlemek","e1":"The novelist limns the characters with great detail.","e1t":"Romancı, karakterleri büyük bir detayla betimliyor.","e2":"","e2t":""},{"w":"lineaments","tr":"yüz hatları / karakteristik özellikler","te":"Noun","tt":"İsim (Plural)","de":"A distinctive feature or characteristic, especially of the face","dt":"Özellikle yüze ait belirgin hatlar veya karakteristik özellikler","e1":"The lineaments of her face.","e1t":"Yüz hatları (çizgileri).","e2":"To recognize the lineaments of a new policy.","e2t":"Yeni bir politikanın ana hatlarını kavramak."},{"w":"liniment","tr":"merhem / ovma ilacı","te":"Noun","tt":"Isim","de":"An embrocation for rubbing on the body to relieve pain from bruises and sprains","dt":"Ağrı veya burkulmalar için vücuda ovularak sürülen ilaçlı sıvı","e1":"To apply a liniment to a sore muscle.","e1t":"Ağrıyan bir kasa merhem sürmek.","e2":"","e2t":""},{"w":"listless","tr":"ilgisiz / cansız / enerjisiz","te":"Adjective","tt":"Sıfat","de":"(Of a person or their manner) lacking energy or enthusiasm","dt":"Enerjisi ve hevesi olmayan (bezgin)","e1":"He felt listless and bored.","e1t":"Kendini bitkin ve sıkılmış hissediyordu.","e2":"A listless performance.","e2t":"Cansız (ruhsuz) bir performans."},{"w":"litany","tr":"litani / uzun ve sıkıcı liste / dua","te":"Noun","tt":"İsim","de":"A tedious recital or repetitive series; or a series of petitions for use in church services","dt":"Birbirini izleyen uzun ve sıkıcı şikayet/olay dizisi; veya ayin duası","e1":"A litany of complaints.","e1t":"Sonu gelmez şikayetler dizisi.","e2":"We had to listen to a litany of his failures.","e2t":"Onun başarısızlıklarının o uzun ve sıkıcı listesini dinlemek zorunda kaldık."},{"w":"litotes","tr":"litotes / olumsuzla onaylama (sanatı)","te":"Noun","tt":"İsim","de":"Ironical understatement in which an affirmative is expressed by the negative of its contrary","dt":"Bir şeyi zıttının olumsuzuyla ifade ederek yapılan abartısız anlatım","e1":"Using \"not bad\" to mean \"very good\" is an example of litotes.","e1t":"\"Fena değil\" diyerek \"çok iyi\"yi kastetmek bir litotes örneğidir.","e2":"","e2t":""},{"w":"lode","tr":"damar (maden) / cevher yatağı","te":"Noun","tt":"İsim","de":"A vein of metal ore in the earth","dt":"Yerin altındaki metal cevheri damarı","e1":"A rich lode of silver.","e1t":"Zengin bir gümüş damarı.","e2":"Mother lode (ana damar / asıl kaynak).","e2t":""},{"w":"loll","tr":"yayılmak / sarkmak / yan gelip yatmak","te":"Verb","tt":"Fiil","de":"Sit, lie, or stand in a lazy, relaxed way; or (of the tongue) to hang out","dt":"Gevşek bir şekilde yayılıp oturmak; veya (dil için) dışarı sarkmak","e1":"He lolled on the sofa all day.","e1t":"Tüm gün kanepede yayıldı.","e2":"The dog's tongue lolled out.","e2t":"Köpeğin dili dışarı sarkmıştı."},{"w":"lope","tr":"uzun adımlarla (rahat) koşmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Run with a long bounding stride","dt":"Uzun ve yaylanan adımlarla (genellikle yorulmadan) koşmak","e1":"The wolf loped across the field.","e1t":"Kurt tarlada uzun adımlarla süzüldü.","e2":"A steady lope.","e2t":"Kararlı ve uzun adımlı bir koşu."},{"w":"lout","tr":"kaba ve hödük adam / hırbo","te":"Noun","tt":"İsim","de":"An uncouth and aggressive man or boy","dt":"Kaba, saygısız ve yordam bilmez erkek","e1":"A drunken lout.","e1t":"Sarhoş bir hırbo (hödük).","e2":"Loutish (adjective).","e2t":"Hödükçe / Kaba."},{"w":"low","tr":"alçak / düşük / böğürmek","te":"Adjective/Verb/Adverb","tt":"Not high; or (of a cow) to make a characteristic deep sound","de":"Alçak; veya (inek için) böğürmek","dt":"Low prices.","e1":"Düşük fiyatlar.","e1t":"To feel low (sad).","e2":"Üzgün (keyifsiz) hissetmek.","e2t":""},{"w":"lucre","tr":"para / kazanç (genellikle kirli/haram)","te":"Noun","tt":"Isim","de":"Money, especially when regarded as sordid or distasteful or gained in a dishonorable way","dt":"Genellikle hoş görülmeyen veya haksız yolla elde edilen para","e1":"Filthy lucre.","e1t":"Kirli kazanç (haraç/rüşvet vb.).","e2":"","e2t":""},{"w":"lumen","tr":"lümen / ışık akısı birimi","te":"Noun","tt":"İsim","de":"The SI unit of luminous flux; or the central cavity of a tubular structure","dt":"Işık akısı birimi; veya (biyolojide) damar gibi tüp şeklindeki yapıların iç boşluğu","e1":"A 100","e1t":"watt bulb emits about 1600 lumens.","e2":"100 watt'lık bir ampul yaklaşık 1600 lümen yayar.","e2t":"The lumen of an artery."},{"w":"lunacy","tr":"çılgınlık / delilik / zırvalık","te":"Noun","tt":"İsim","de":"The state of being a lunatic; insanity (formerly believed to be related to the moon)","dt":"Delilik veya çok büyük saçmalık/risk","e1":"It would be sheer lunacy to go out in this storm.","e1t":"Bu fırtınada dışarı çıkmak tam bir delilik (çılgınlık) olur.","e2":"Lunatic (noun/adj).","e2t":"Deli / Çılgın."},{"w":"lunge","tr":"hamle yapmak / fırlamak / hamle","te":"Verb/Noun","tt":"Fiil/İsim","de":"A sudden forward thrust of the body, typically with an arm or leg extended","dt":"Genellikle kılıçla veya spor yaparken yapılan ani ileri hamle","e1":"He made a lunge for the ball.","e1t":"Topa doğru bir hamle yaptı.","e2":"The dog lunged at the intruder.","e2t":"Köpek davetsiz misafirin üzerine atıldı (hamle yaptı)."},{"w":"lurk","tr":"pusuya yatmak / gizlenmek / (internette) sessizce izlemek","te":"Verb","tt":"Fiil","de":"Be or remain hidden so as to wait in ambush for someone or something","dt":"Pusu kurmak için gizlenmek; veya (sorun vb. için) altta yatan","e1":"A suspicious man was lurking in the shadows.","e1t":"Gölgelerde gizlenen (pusuya yatmış) şüpheli bir adam.","e2":"Hidden dangers lurk beneath the surface.","e2t":"Yüzeyin altında gizli tehlikeler yatıyor."},{"w":"luscious","tr":"tatlı ve sulu / nefis / çekici","te":"Adjective","tt":"Sıfat","de":"(Of food or wine) having a pleasingly rich, sweet taste; or very attractive","dt":"(Yemek için) çok lezzetli, sulu ve tatlı; veya çok çekici","e1":"Luscious peaches.","e1t":"Tatlı ve sulu şeftaliler.","e2":"Luscious colors.","e2t":"Göz alıcı (zengin) renkler."},{"w":"luster / lustre","tr":"parlaklık / cila / şan / şeref","te":"Noun/Verb","tt":"İsim/Fiil","de":"A gentle sheen or soft glow, especially of a partly reflective surface; or glory","dt":"Yumuşak parlaklık (ışıltı); veya (mecazi) şan/şöhret","e1":"The luster of a pearl.","e1t":"Bir incinin parıltısı.","e2":"To add luster to one's reputation.","e2t":"İtibarına itibar katmak (parlatmak)."},{"w":"mace","tr":"topuz (silah) / tören asası / bir tür baharat","te":"Noun","tt":"İsim","de":"A heavy club with a spiked metal head; or an ornamental staff; or a spice","dt":"Ucu çivili ağır topuz; veya törenlerde taşınan asa; veya (küçük hindistan cevizi kabuğundan yapılan) baharat","e1":"The knight carried a mace.","e1t":"Şövalye bir topuz taşıyordu.","e2":"Chemical mace (tear gas).","e2t":"Göz yaşartıcı sprey."},{"w":"macerate","tr":"(sıvıda) yumuşatmak / suda bırakmak","te":"Verb","tt":"Fiil","de":"(Especially with reference to food) soften or become softened by soaking in a liquid","dt":"(Özellikle yemeği) bir sıvı içinde bekleterek yumuşatmak","e1":"Macerated fruit.","e1t":"Şerbete yatırılmış (yumuşatılmış) meyve.","e2":"The skin becomes macerated if kept wet.","e2t":"Deri ıslak tutulursa yumuşar (bozulur)."},{"w":"machiavellian","tr":"makyavelist / sinsi / amaca giden her yolu mübah sayan","te":"Adjective","tt":"Sıfat","de":"Cunning, scheming, and unscrupulous, especially in politics","dt":"Siyasette kurnaz, çıkarcı ve ahlak dışı yöntemler kullanan","e1":"A Machiavellian plot.","e1t":"Sinsi ve çıkarcı bir plan.","e2":"His Machiavellian tactics.","e2t":"Onun Makyavelist (amaca odaklı kurnaz) taktikleri."},{"w":"maculated","tr":"lekeli / benekli","te":"Adjective","tt":"Sıfat","de":"Spotted; stained","dt":"Üzerinde lekeler veya benekler olan","e1":"A maculated skin.","e1t":"Lekeli cilt.","e2":"(Not: Immaculate","e2t":"lekesiz"},{"w":"madrigal","tr":"madrigal / çok sesli şarkı","te":"Noun","tt":"İsim","de":"A part","dt":"song for several voices, especially one of the Renaissance period","e1":"Rönesans dönemine ait, genellikle din dışı ve çok sesli koro şarkısı","e1t":"To sing an English madrigal.","e2":"Bir İngiliz madrigali söylemek.","e2t":""},{"w":"maelstrom","tr":"anafor / büyük girdap / kargaşa","te":"Noun","tt":"İsim","de":"A powerful whirlpool in the sea or a river; or a state of confused and violent movement","dt":"Güçlü deniz girdabı; veya (mecazi) büyük karmaşa/keşmekeş","e1":"To be caught in a maelstrom of emotions.","e1t":"Duygu karmaşasının (anaforunun) içinde kalmak.","e2":"The maelstrom of war.","e2t":"Savaşın keşmekeşi."},{"w":"magisterial","tr":"otoriter / hakimvari / emredici","te":"Adjective","tt":"Sıfat","de":"Having or showing great authority; or relating to a magistrate","dt":"Büyük bir otoriteye sahip (amirane); veya yargıçla ilgili","e1":"A magisterial tone of voice.","e1t":"Otoriter (üstten bakan) bir ses tonu.","e2":"His magisterial study of history.","e2t":"Tarih üzerine yaptığı o yetkin (muazzam) çalışma."},{"w":"magnanimity","tr":"alçakgönüllülük / büyüklük / yüce gönüllülük","te":"Noun","tt":"İsim","de":"The virtue of being magnanimous; generosity","dt":"Özellikle düşmana veya rakiplere karşı gösterilen asillik ve cömertlik","e1":"The victor showed great magnanimity.","e1t":"Galip gelen taraf büyük bir yüce gönüllülük gösterdi.","e2":"Magnanimous (adjective).","e2t":"Yüce gönüllü."},{"w":"magnificence","tr":"görkem / ihtişam / heybet","te":"Noun","tt":"İsim","de":"The quality of being magnificent; splendor","dt":"Muazzamlık ve etkileyicilik durumu","e1":"The magnificence of the royal palace.","e1t":"Kraliyet sarayının ihtişamı.","e2":"Magnificent (adjective).","e2t":"Görkemli."},{"w":"magniloquent","tr":"ağdalı konuşan / abartılı (dil)","te":"Adjective","tt":"Sıfat","de":"Using high","dt":"flown or bombastic language","e1":"Büyük ve süslü kelimeler kullanarak etkilemeye çalışan (ağdalı)","e1t":"A magniloquent orator.","e2":"Ağdalı konuşan hatip.","e2t":"(Not: Grandiloquent ile eş anlamlıdır)."},{"w":"mainspring","tr":"ana yay (saat vb.) / asıl neden / itici güç","te":"Noun","tt":"İsim","de":"The principal spring of a watch or clock; or the motivating force","dt":"Saatin ana yayı; veya (mecazi) bir olayın en temel itici gücü/nedeni","e1":"The mainspring of the revolution.","e1t":"Devrimin ana itici gücü.","e2":"To break the mainspring of a watch.","e2t":"Saatin zembereğini (ana yayını) bozmak."},{"w":"mainstay","tr":"dayanak / ana direk / temel direk","te":"Noun","tt":"İsim","de":"A person or thing on which something else is based or depends","dt":"Bir şeyin ayakta kalmasını sağlayan en önemli destek/dayanak","e1":"Tourism is the mainstay of the economy.","e1t":"Turizm ekonominin temel direğidir.","e2":"He is the mainstay of the family.","e2t":"O, ailenin direğidir (dayanağıdır)."},{"w":"maize","tr":"mısır (bitki)","te":"Noun","tt":"İsim","de":"British term for corn","dt":"Mısır bitkisi (İngiliz İngilizcesinde yaygındır)","e1":"A field of maize.","e1t":"Mısır tarlası.","e2":"","e2t":""},{"w":"malapropism","tr":"kelime karıştırma / sözcük hatası","te":"Noun","tt":"İsim","de":"The mistaken use of a word in place of a similar","dt":"sounding one, often with an amusing effect","e1":"Bir kelimenin sesçe benzeriyle (komik şekilde) yanlış kullanılması","e1t":"To say \"recession\" instead of \"procession\" is a malapropism.","e2":"\"Procession\" (tören) yerine \"recession\" (durgunluk) demek bir kelime hatasıdır.","e2t":""},{"w":"malicious","tr":"kötü niyetli / haince / habis","te":"Adjective","tt":"Sıfat","de":"Intending or intended to do harm","dt":"Başkasına zarar vermeyi amaçlayan; haince","e1":"Malicious rumors.","e1t":"Kötü niyetli (asılsız) söylentiler.","e2":"Malicious software (malware).","e2t":"Kötü amaçlı yazılım."},{"w":"manacle","tr":"kelepçelemek / pranga vurmak / kelepçe","te":"Verb/Noun","tt":"Fiil/İsim","de":"Shackle; or a metal band or chain for fastening a person's hands or ankles","dt":"El veya ayak bileklerine takılan metal halka (kelepçe); veya kelepçelemek","e1":"His hands were manacled behind his back.","e1t":"Elleri arkasından kelepçelendi.","e2":"To break the manacles of tradition.","e2t":"Geleneğin prangalarını (bağlarını) kırmak."},{"w":"mangy","tr":"uyuz (hayvan) / bakımsız / sefil","te":"Adjective","tt":"Sıfat","de":"Having mange (a skin disease); or shabby in appearance","dt":"Uyuz hastalığı olan; veya perişan, bakımsız ve eski görünümlü","e1":"A mangy dog.","e1t":"Uyuz bir köpek.","e2":"A mangy old carpet.","e2t":"Eskimiş ve dökülen (sefil) bir halı."},{"w":"maniacal","tr":"manyakça / çılgınca","te":"Adjective","tt":"Sıfat","de":"Characterized by ungovernable excitement or frenzy; or relating to mania","dt":"Kontrol edilemeyen bir çılgınlık veya manyaklık içeren","e1":"Maniacal laughter.","e1t":"Manyakça (çılgınca) bir kahkaha.","e2":"Maniacal energy.","e2t":"Çılgınca bir enerji."},{"w":"manumit","tr":"azat etmek / kölelikten kurtarmak","te":"Verb","tt":"Fiil","de":"Release from slavery; set free","dt":"Bir köleyi veya bağımlıyı özgürlüğüne kavuşturmak","e1":"He manumitted his slaves in his will.","e1t":"Vasiyetinde kölelerini azat etti.","e2":"Manumission (noun).","e2t":"Azat etme."},{"w":"manure","tr":"gübre / gübrelemek","te":"Noun/Verb","tt":"İsim/Fiil","de":"Animal dung used for fertilizing land","dt":"Toprağı verimlileştirmek için kullanılan hayvan dışkısı","e1":"To spread manure on the fields.","e1t":"Tarlaya gübre sermek.","e2":"Green manure.","e2t":"Yeşil gübre."},{"w":"marionette","tr":"marionet / ipli kukla","te":"Noun","tt":"İsim","de":"A puppet worked from above by strings attached to its limbs","dt":"Uzuvlarına bağlı iplerle yukarıdan yönetilen kukla","e1":"He felt like a marionette in the hands of the boss.","e1t":"Patronun ellerinde bir ipli kukla gibi hissetti.","e2":"A marionette show.","e2t":"Kukla gösterisi."},{"w":"marrow","tr":"ilik / öz / kabak (İngiltere)","te":"Noun","tt":"İsim","de":"A soft fatty substance in the cavities of bones; or the essential part of something","dt":"Kemik iliği; veya bir şeyin en temel (öz) kısmı","e1":"Bone marrow.","e1t":"Kemik iliği.","e2":"To the marrow of his bones.","e2t":"İliğine kadar (derinden)."},{"w":"marsupial","tr":"keseli (hayvan)","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A mammal of an order whose members are born incompletely developed and are typically carried in a pouch on the mother's belly","dt":"Yavrularını karınlarındaki kesede taşıyan memeli türü","e1":"Kangaroos and koalas are marsupials.","e1t":"Kangurular ve koalalar keselidir.","e2":"","e2t":""},{"w":"masochist","tr":"mazoşist / kendine acı çektirmekten zevk alan","te":"Noun","tt":"İsim","de":"A person who derives gratification from their own pain or humiliation","dt":"Kendi çektiği acıdan veya aşağılanmaktan zevk alan kişi","e1":"He is a bit of a masochist when it comes to exercise.","e1t":"Egzersiz konusunda biraz mazoşisttir (kendini çok zorlar).","e2":"Masochism (noun).","e2t":"Mazoşizm."},{"w":"masticate","tr":"çiğnemek","te":"Verb","tt":"Fiil","de":"Chew (food)","dt":"(Yemeği) çiğnemek","e1":"It is important to masticate your food thoroughly.","e1t":"Yemeğinizi iyice çiğnemeniz önemlidir.","e2":"Mastication (noun).","e2t":"Çiğneme."},{"w":"materialism","tr":"materyalizm / maddecilik","te":"Noun","tt":"İsim","de":"A tendency to consider material possessions and physical comfort as more important than spiritual values","dt":"Maddi varlıklara ve konfora manevi değerlerden daha fazla önem verme eğilimi","e1":"The materialism of modern society.","e1t":"Modern toplumun maddeciliği (tüketim çılgınlığı).","e2":"Materialist (noun/adj).","e2t":"Materyalist."},{"w":"matriarch","tr":"anaerkil lider / ailenin kadın reisi","te":"Noun","tt":"İsim","de":"A woman who is the head of a family or tribe","dt":"Bir ailenin, kabilenin veya grubun başındaki kadın","e1":"The family matriarch.","e1t":"Ailenin kadın reisi (genellikle en yaşlı kadın).","e2":"Matriarchy (noun).","e2t":"Anaerkillik. (Not: Patriarch"},{"w":"matriculate","tr":"üniversiteye kaydolmak / üniversiteli olmak","te":"Verb","tt":"Fiil","de":"Enrol at a college or university","dt":"Bir yükseköğretim kurumuna (genellikle törenle) kaydolmak","e1":"He matriculated at Oxford last year.","e1t":"Geçen yıl Oxford'a kaydoldu.","e2":"Matriculation (noun).","e2t":"Üniversite kaydı."},{"w":"mausoleum","tr":"mozole / anıt mezar","te":"Noun","tt":"İsim","de":"A stately or impressive building housing a tomb or tombs","dt":"Görkemli ve büyük anıt mezar","e1":"The Mausoleum at Halicarnassus.","e1t":"Halikarnas Mozolesi.","e2":"Anitkabir is a magnificent mausoleum.","e2t":"Anıtkabir muhteşem bir anıt mezardır."},{"w":"mauve","tr":"leylak rengi / eflatun","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A pale purple color","dt":"Soluk mor veya eflatun renk","e1":"A mauve dress.","e1t":"Leylak rengi bir elbise.","e2":"The sky turned mauve at sunset.","e2t":"Gün batımında gökyüzü eflatun bir renk aldı."},{"w":"mayhem","tr":"kargaşa / kaos / kırım / sakatlama","te":"Noun","tt":"İsim","de":"Violent or needless disorder; chaos","dt":"Şiddetli kargaşa veya büyük kaos","e1":"There was complete mayhem after the explosion.","e1t":"Patlamadan sonra tam bir kaos yaşandı.","e2":"To cause mayhem.","e2t":"Kargaşaya yol açmak."},{"w":"meager / meagre","tr":"kıt / az / yetersiz / cılız","te":"Adjective","tt":"Sıfat","de":"(Of something provided or available) lacking in quantity or quality; lean","dt":"Miktar veya kalite olarak yetersiz; çok az","e1":"A meager salary.","e1t":"Kıt (yetersiz) bir maaş.","e2":"Meager resources.","e2t":"Kısıtlı kaynaklar."},{"w":"megalomania","tr":"megalomani / büyüklük tutkusu","te":"Noun","tt":"İsim","de":"Obsession with the exercise of power, especially in the domination of others","dt":"Güç sahibi olma ve başkalarına hükmetme saplantısı","e1":"The dictator was suffering from megalomania.","e1t":"Diktatör megalomaniden (büyüklük hezeyanından) muzdaripti.","e2":"Megalomaniac (noun/adj).","e2t":"Megaloman."},{"w":"melee / mêlée","tr":"arbede / kargaşa / meydan kavgası","te":"Noun","tt":"İsim","de":"A confused fight, skirmish, or scuffle; or a confused mass of people","dt":"İnsanların birbirine girdiği karışık kavga veya kalabalık","e1":"Several people were injured in the melee.","e1t":"Arbedede (meydan kavgasında) birkaç kişi yaralandı.","e2":"To be lost in the melee of the crowd.","e2t":"Kalabalık keşmekeşinde kaybolmak."},{"w":"mercantile","tr":"ticari / ticaretle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to merchants or trading","dt":"Tüccarlarla veya ticaretle ilgili","e1":"A mercantile law.","e1t":"Ticaret hukuku.","e2":"Mercantile system.","e2t":"Merkantilist sistem."},{"w":"meretricious","tr":"yapmacık / gösterişli ama değersiz / aldatıcı","te":"Adjective","tt":"Sıfat","de":"Apparently attractive but having in reality no value or integrity","dt":"Dıştan çekici görünen ancak aslında değersiz ve sahte olan","e1":"Meretricious decorations.","e1t":"Göz boyayan (ama kalitesiz) süslemeler.","e2":"A meretricious argument.","e2t":"Aldatıcı (boş) bir iddia."},{"w":"mesa","tr":"tabla dağ / düz tepeli dağ","te":"Noun","tt":"İsim","de":"An isolated flat","dt":"topped hill with steep sides","e1":"Dik yamaçlı ve tepesi düz olan izole dağ/tepe","e1t":"The vast mesas of Arizona.","e2":"Arizona'nın uçsuz buçaksız tabla dağları.","e2t":""},{"w":"metallurgy","tr":"metalurji / metal bilimi","te":"Noun","tt":"İsim","de":"The branch of science and technology concerned with the properties of metals and their production and purification","dt":"Metallerin özellikleri, üretimi ve saflaştırılması ile ilgilenen bilim dalı","e1":"A degree in metallurgy.","e1t":"Metalurji diploması.","e2":"Metallurgical engineer.","e2t":"Metalurji mühendisi."},{"w":"mete","tr":"paylaştırmak / (ceza vb.) vermek","te":"Verb","tt":"Fiil","de":"Dispense or allot justice, a punishment, or harsh treatment","dt":"(Özellikle ceza veya adalet) dağıtmak veya uygulamak","e1":"Punishment was meted out to the guilty.","e1t":"Suçlulara ceza verildi (dağıtıldı).","e2":"To mete out justice.","e2t":"Adalet dağıtmak."},{"w":"meteoric","tr":"meteora ait / çok hızlı ve parlak","te":"Adjective","tt":"Sıfat","de":"Relating to meteors; or (of a career) very rapid and brilliant","dt":"Meteorlarla ilgili; veya (kariyer için) aniden parlayan ve çok hızlı yükselen","e1":"A meteoric rise to fame.","e1t":"Şöhrete giden çok hızlı ve parlak bir yükseliş.","e2":"Meteoric shower.","e2t":"Meteor yağmuru."},{"w":"methodical / methodic","tr":"sistemli / düzenli / metodik","te":"Adjective","tt":"Sıfat","de":"Done according to a systematic or established form of procedure","dt":"Belirli bir düzene veya yönteme göre yapılan","e1":"A methodical approach to work.","e1t":"İşe sistemli bir yaklaşım.","e2":"She is very methodical in her organizing.","e2t":"Organizasyon konusunda çok düzenlidir."},{"w":"metrical","tr":"ölçülü (şiir/müzik) / metrik","te":"Adjective","tt":"Sıfat","de":"Relating to or composed in poetic meter","dt":"Şiir ölçüsü (aruz/hece vb.) ile ilgili veya bu ölçüde yazılmış","e1":"The metrical structure of the poem.","e1t":"Şiirin vezin (ölçü) yapısı.","e2":"Metrical feet.","e2t":"Şiir durakları (ayakları)."},{"w":"metropolis","tr":"metropol / ana kent","te":"Noun","tt":"İsim","de":"The capital or chief city of a country or region","dt":"Bir ülkenin veya bölgenin en büyük ve en önemli şehri","e1":"The bustling metropolis of Istanbul.","e1t":"Hareketli İstanbul metropolü.","e2":"Metropolitan (adjective).","e2t":"Metropole ait."},{"w":"mime","tr":"pandomim / mim sanatçısı / taklit etmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"The theatrical technique of suggesting action, character, or emotion without words, using only gesture, expression, and movement","dt":"Sözsüz, sadece hareketlerle yapılan tiyatro sanatı","e1":"To perform a mime.","e1t":"Pandomim yapmak.","e2":"He mimed the action of eating.","e2t":"Yemek yeme hareketini taklit etti."},{"w":"mincing","tr":"yapmacık (yürüyüş/tavır) / nazlı","te":"Adjective","tt":"Sıfat","de":"(Of a person's manner or gait) affectedly dainty or elegant","dt":"Yapmacık ve nazlı bir şekilde (genellikle küçük adımlarla) yürüyen/konuşan","e1":"He walked with mincing steps.","e1t":"Nazlı (yapmacık) adımlarla yürüdü.","e2":"(Not: Mince","e2t":"kıyma"},{"w":"minuscule / miniscule","tr":"minicik / çok küçük","te":"Adjective","tt":"Sıfat","de":"Extremely small; tiny","dt":"Çok küçük, ufacık","e1":"A minuscule amount of money.","e1t":"Minicik (çok az) bir para.","e2":"The chances of success are minuscule.","e2t":"Başarı şansı çok düşüktür."},{"w":"minute","tr":"dakika / tutanak / çok küçük (may","te":"nyut)","tt":"Noun/Verb/Adjective","de":"A period of time (60 seconds); or a formal record of a meeting; or (adj) extremely small","dt":"Dakika; veya toplantı tutanağı; veya (sıfat) çok küçük/detaylı","e1":"Just a minute, please.","e1t":"Bir dakika lütfen.","e2":"To take the minutes of a meeting.","e2t":"Toplantı tutanağını tutmak."},{"w":"minutiae","tr":"ayrıntılar / önemsiz detaylar","te":"Noun","tt":"İsim (Plural)","de":"The small, precise, or trivial details of something","dt":"Bir şeyin çok küçük, hassas veya önemsiz görünen detayları","e1":"He was lost in the minutiae of the contract.","e1t":"Sözleşmenin ayrıntıları arasında kayboldu.","e2":"To focus on the minutiae rather than the big picture.","e2t":"Büyük resim yerine ufak tefek detaylara odaklanmak."},{"w":"mischance","tr":"aksilik / talihsizlik / kem talih","te":"Noun","tt":"İsim","de":"Bad luck","dt":"Kötü şans veya talihsiz olay","e1":"By some mischance, the letter never arrived.","e1t":"Bir aksilik sonucu mektup hiç ulaşmadı.","e2":"A pure mischance.","e2t":"Tamamen bir talihsizlik."},{"w":"misconception","tr":"yanlış kanı / yanlış düşünce","te":"Noun","tt":"İsim","de":"A view or opinion that is incorrect because based on faulty thinking or understanding","dt":"Hatalı düşünceye dayanan yanlış fikir/kanan","e1":"A common misconception about bats.","e1t":"Yarasalar hakkında yaygın bir yanlış kanı.","e2":"To correct a misconception.","e2t":"Yanlış bir düşünceyi düzeltmek."},{"w":"mite","tr":"zerre / bit (parazit) / küçük çocuk / azıcık","te":"Noun","tt":"İsim","de":"A minute arachnid which has four pairs of legs; or a very small amount; or a small child","dt":"Akar (mayt/bit); veya çok küçük miktar; veya küçük çocuk","e1":"Dust mites.","e1t":"Toz akarları.","e2":"It's a mite (a bit) too small.","e2t":"Bir gıdım (birazcık) fazla küçük."},{"w":"molten","tr":"erimiş (ısıdan)","te":"Adjective","tt":"Sıfat","de":"(Especially of materials with a high melting point, such as metal or glass) liquefied by heat","dt":"(Özellikle metal veya cam gibi) yüksek ısıda eritilmiş","e1":"Molten lava.","e1t":"Erimiş lav.","e2":"Molten lead.","e2t":"Erimiş kurşun."},{"w":"monolith","tr":"monolit / tek parça dev taş / devasa yapı","te":"Noun","tt":"İsim","de":"A large single upright block of stone, especially one shaped into or serving as a monument; or a large powerful organization","dt":"Tek parça büyük taş blok; veya (mecazi) devasa ve hantal yapı/kurum","e1":"Ancient monoliths like Stonehenge.","e1t":"Stonehenge gibi antik monolitler.","e2":"The party is no longer a monolith.","e2t":"Parti artık tek vücut (tek parça) bir dev değil."},{"w":"monologue","tr":"monolog / tek kişilik konuşma","te":"Noun","tt":"İsim","de":"A long speech by one actor in a play or movie; or a long tedious speech by one person in a conversation","dt":"Tek bir kişinin yaptığı uzun konuşma","e1":"A dramatic monologue.","e1t":"Dramatik monolog.","e2":"He dominated the dinner with a long monologue.","e2t":"Yemeği tek başına yaptığı uzun bir konuşmayla domine etti. (Not: Dialogue"},{"w":"monotheism","tr":"monoteizm / tektanrıcılık","te":"Noun","tt":"İsim","de":"The doctrine or belief that there is only one God","dt":"Sadece tek bir Tanrı'nın varlığına olan inanç","e1":"Islam is a form of monotheism.","e1t":"İslam bir monoteizm (tektanrıcılık) biçimidir.","e2":"Monotheistic (adjective).","e2t":"Tektanrılı. (Not: Polytheism"},{"w":"moody","tr":"huysuz / dengesiz (ruh hali) / melankolik","te":"Adjective","tt":"Sıfat","de":"(Of a person) given to unpredictable changes of mood, especially sudden bouts of gloominess","dt":"Ruh hali çabuk değişen (genellikle asabi veya hüzünlü)","e1":"A moody teenager.","e1t":"Huysuz (dengesiz) bir genç.","e2":"Moody music.","e2t":"Hüzünlü (atmosferik) müzik."},{"w":"mordant","tr":"iğneleyici / keskin / mordan (boya sabitleyici)","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Especially of humor) having or showing a sharp or critical quality; biting","dt":"(Özellikle mizah için) iğneleyici, keskin (acımasız); veya boya sabitleyici madde","e1":"Mordant wit.","e1t":"İğneleyici zeka (mizah).","e2":"Mordant remarks.","e2t":"Keskin ve kırıcı yorumlar."},{"w":"mortician","tr":"cenaze levazımcısı","te":"Noun","tt":"İsim","de":"An undertaker","dt":"Cenaze işlerini düzenleyen kişi","e1":"The mortician prepared the body for the funeral.","e1t":"Cenaze levazımcısı cesedi cenaze töreni için hazırladı.","e2":"","e2t":""},{"w":"mote","tr":"zerre / toz parçası","te":"Noun","tt":"İsim","de":"A tiny piece of a substance","dt":"Havada uçuşan çok küçük toz veya madde parçası","e1":"A mote of dust in a sunbeam.","e1t":"Güneş ışığında uçuşan bir toz zerresi.","e2":"","e2t":""},{"w":"motif","tr":"motif / tema","te":"Noun","tt":"İsim","de":"A decorative design or pattern; or a distinctive feature or dominant idea in an artistic or literary composition","dt":"Sanatsal bir eserde tekrarlanan ana öğe, desen veya tema","e1":"A floral motif.","e1t":"Çiçekli motif.","e2":"The motif of revenge in the play.","e2t":"Oyundaki intikam teması (motifi)."},{"w":"motility","tr":"hareketlilik / hareket yeteneği","te":"Noun","tt":"İsim","de":"The ability of an organism to move independently, using metabolic energy","dt":"Bir organizmanın veya hücrenin kendiliğinden hareket edebilme yeteneği","e1":"Sperm motility.","e1t":"Sperm hareketliliği.","e2":"Gastric motility.","e2t":"Mide hareketliliği."},{"w":"mottled","tr":"lekeli / alacalı / benekli","te":"Adjective","tt":"Sıfat","de":"Marked with spots or smears of color","dt":"Farklı renklerde lekeleri veya benekleri olan","e1":"Mottled skin.","e1t":"Lekeli (alacalı) cilt.","e2":"The mottled green leaves.","e2t":"Benekli yeşil yapraklar."},{"w":"muggy","tr":"nemli ve boğucu (hava)","te":"Adjective","tt":"Sıfat","de":"(Of the weather) unpleasantly warm and humid","dt":"Rahatsız edici derecede sıcak ve nemli hava","e1":"A hot, muggy day.","e1t":"Sıcak ve boğucu bir gün.","e2":"","e2t":""},{"w":"mulct","tr":"para cezasına çarptırmak / dolandırmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Extract money from (someone) by fine or taxation; or to defraud","dt":"Birini para cezasına çarptırmak; veya parasını hileyle almak","e1":"He was mulcted of his savings by a con artist.","e1t":"Bir dolandırıcı tarafından birikimleri elinden alındı (dolandırıldı).","e2":"","e2t":""},{"w":"multiform","tr":"çok biçimli / çeşitli şekillerde","te":"Adjective","tt":"Sıfat","de":"Existing in many forms or kinds","dt":"Pek çok formda veya türde var olan","e1":"A multiform disease.","e1t":"Çok biçimli (farklı şekillerde seyreden) bir hastalık.","e2":"Multiformity (noun).","e2t":"Çok biçimlilik."},{"w":"multilingual","tr":"çok dilli","te":"Adjective","tt":"Sıfat","de":"In or using several languages","dt":"Birkaç dil bilen veya birkaç dilde olan","e1":"A multilingual dictionary.","e1t":"Çok dilli sözlük.","e2":"She is multilingual.","e2t":"O çok dilli biridir (birkaç dil konuşur)."},{"w":"musky","tr":"misk kokulu","te":"Adjective","tt":"Sıfat","de":"Resembling the smell of musk","dt":"Misk gibi kokan (genellikle ağır ve odunsu koku)","e1":"A musky perfume.","e1t":"Misk kokulu bir parfüm.","e2":"Musk (noun).","e2t":"Misk."},{"w":"mutability","tr":"değişkenlik / kararsızlık","te":"Noun","tt":"İsim","de":"Liability or tendency to change","dt":"Değişebilir olma durumu","e1":"The mutability of fashion.","e1t":"Modanın değişkenliği.","e2":"Mutable (adjective).","e2t":"Değişken."},{"w":"muted","tr":"boğuk (ses) / mat (renk) / sessiz","te":"Adjective","tt":"Sıfat","de":"(Of a sound or color) not bright or loud","dt":"(Ses için) kısılmış veya boğuk; (renk için) soluk/mat; (tepki için) sakin","e1":"Muted colors.","e1t":"Mat (göze çarpmayan) renkler.","e2":"A muted reaction.","e2t":"Cılız (sessiz) bir tepki."},{"w":"mystic","tr":"mistik / gizemci / tasavvufi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who seeks by contemplation and self","dt":"surrender to obtain unity with or absorption into the Deity or the absolute","e1":"Gizli gerçeklere sezgiyle ulaşmaya çalışan kişi; veya doğaüstü","e1t":"A mystic experience.","e2":"Mistik bir deneyim.","e2t":"Mysticism (noun)."},{"w":"mythical","tr":"efsanevi / hayali","te":"Adjective","tt":"Sıfat","de":"Occurring in or characteristic of myths or folk tales; or idealized","dt":"Efsanelerde geçen; veya gerçek olmayan, hayali","e1":"Mythical creatures like dragons.","e1t":"Ejderhalar gibi efsanevi yaratıklar.","e2":"A mythical land.","e2t":"Hayali bir ülke."},{"w":"naïve / naive","tr":"saf / toy / deneyimsiz","te":"Adjective","tt":"Sıfat","de":"(Of a person or action) showing a lack of experience, wisdom, or judgment","dt":"Tecrübesiz olduğu için her şeye kolayca inanan","e1":"It was naïve of you to believe him.","e1t":"Ona inanman senin saflığındı.","e2":"A naïve art style.","e2t":"Çocuksu (yalın) bir sanat tarzı."},{"w":"natal","tr":"doğumla ilgili / doğuma ait","te":"Adjective","tt":"Sıfat","de":"Relating to the place or time of one's birth","dt":"Doğum yeri veya zamanı ile ilgili","e1":"Natal day (birthday).","e1t":"Doğum günü.","e2":"One's natal home.","e2t":"Doğulan ev."},{"w":"natation","tr":"yüzme / yüzme sanatı","te":"Noun","tt":"İsim","de":"Swimming","dt":"Yüzme veya yüzme yeteneği","e1":"Natatorial (adjective).","e1t":"Yüzmeye dair.","e2":"","e2t":""},{"w":"natty","tr":"şık / zarif / derli toplu","te":"Adjective","tt":"Sıfat","de":"(Of a person or an article of clothing) smart and fashionable","dt":"(Kişi veya kıyafet için) çok şık, titiz ve düzgün","e1":"A natty suit.","e1t":"Şık bir takım elbise.","e2":"He is a natty dresser.","e2t":"Çok şık giyinen biridir."},{"w":"nectar","tr":"nektar / bal özü / nefis içecek","te":"Noun","tt":"İsim","de":"A sugary fluid secreted by plants, especially within flowers to encourage pollination by insects; or a delicious drink","dt":"Çiçeklerin salgıladığı tatlı sıvı; veya (mitolojide) tanrıların içeceği; veya çok lezzetli içecek","e1":"Bees collecting nectar.","e1t":"Bal özü toplayan arılar.","e2":"This juice is pure nectar.","e2t":"Bu meyve suyu resmen iksir (nefis)."},{"w":"nether","tr":"alttaki / alt","te":"Adjective","tt":"Sıfat","de":"Lower in position","dt":"Konum olarak daha aşağıda bulunan","e1":"The nether regions of the earth.","e1t":"Dünyanın alt tabakaları (yer altı).","e2":"Nether lip.","e2t":"Alt dudak."},{"w":"nib","tr":"(kalem) ucu","te":"Noun","tt":"İsim","de":"The pointed end part of a pen, which distributes the ink on the writing surface","dt":"Dolmakalem veya tüy kalemin kağıda değen metal ucu","e1":"A gold nib.","e1t":"Altın kalem ucu.","e2":"To change the nib of the pen.","e2t":"Kalemin ucunu değiştirmek."},{"w":"nihilism","tr":"nihilizm / hiççilik","te":"Noun","tt":"İsim","de":"The rejection of all religious and moral principles, often in the belief that life is meaningless","dt":"Tüm dini ve ahlaki ilkelerin reddedilmesi; hayatın anlamsız olduğu inancı","e1":"His philosophy was one of pure nihilism.","e1t":"Onun felsefesi tam bir nihilizmdi.","e2":"Nihilist (noun/adj).","e2t":"Nihilist."},{"w":"nomenclature","tr":"terminoloji / adlandırma sistemi","te":"Noun","tt":"İsim","de":"The devising or choosing of names for things, especially in a science or other discipline","dt":"Özellikle bilim dallarında kullanılan terimler dizisi veya adlandırma yöntemi","e1":"Chemical nomenclature.","e1t":"Kimyasal adlandırma sistemi.","e2":"The technical nomenclature of biology.","e2t":"Biyolojinin teknik terminolojisi."},{"w":"noncommittal","tr":"suya sabuna dokunmayan / tarafsız / çekimser","te":"Adjective","tt":"Sıfat","de":"Not displaying a definite opinion or course of action","dt":"Belirli bir fikir belirtmekten veya taraf tutmaktan kaçınan","e1":"He gave a noncommittal answer.","e1t":"Kaçamak (tarafını belli etmeyen) bir cevap verdi.","e2":"Her attitude remained noncommittal.","e2t":"Tavrı çekimser kaldı."},{"w":"nubile","tr":"evlenecek çağda (genç kadın) / çekici","te":"Adjective","tt":"Sıfat","de":"(Of a young woman) suitable for marriage; sexually attractive","dt":"Evlilik çağına gelmiş ve fiziksel olarak çekici genç kadın","e1":"A group of nubile young women.","e1t":"Evlilik çağında çekici genç kadınlar grubu.","e2":"","e2t":""},{"w":"nugatory","tr":"değersiz / etkisiz / boş","te":"Adjective","tt":"Sıfat","de":"Of no value or importance; useless; futile","dt":"Hiçbir değeri veya etkisi olmayan; boşuna","e1":"A nugatory effort.","e1t":"Nafile (sonuçsuz) bir çaba.","e2":"The contract was rendered nugatory.","e2t":"Sözleşme hükümsüz (etkisiz) kılındı."},{"w":"numismatist","tr":"nümismat / madeni para koleksiyoncusu","te":"Noun","tt":"İsim","de":"A person who collects or studies coins or medals","dt":"Eski para veya madalya uzmanı/koleksiyoncusu","e1":"Numismatics (noun).","e1t":"Nümismatik (para bilimi).","e2":"","e2t":""},{"w":"obeisance","tr":"saygı / baş eğme / hürmet","te":"Noun","tt":"İsim","de":"A gesture expressing deferential respect, such as a bow or curtsy","dt":"Saygı göstermek için eğilme veya genel anlamda hürmet","e1":"To make an obeisance to the king.","e1t":"Kralın önünde saygıyla eğilmek.","e2":"An act of obeisance.","e2t":"Bir hürmet gösterisi."},{"w":"obsidian","tr":"obsidyen / volkan camı","te":"Noun","tt":"İsim","de":"A hard, dark, glass","dt":"like volcanic rock formed by the rapid solidification of lava without crystallization","e1":"Lavın hızla soğumasıyla oluşan, cam gibi parlak ve sert volkanik kayaç","e1t":"Ancient people made tools from obsidian.","e2":"Antik insanlar obsidyenden aletler yapardı.","e2t":""},{"w":"occidental","tr":"batılı / batıya ait","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Relating to the countries of the West","dt":"Batı ülkeleriyle (Avrupa/Amerika) ilgili","e1":"Occidental culture.","e1t":"Batı kültürü.","e2":"(Not: Oriental","e2t":"doğulu"},{"w":"occupancy","tr":"işgal / oturma / doluluk (oranı)","te":"Noun","tt":"İsim","de":"The action or fact of occupying a place; or the proportion of accommodation occupied","dt":"Bir yerde oturma/bulunma durumu; veya (otel vb.) doluluk oranı","e1":"Hotel occupancy rates.","e1t":"Otel doluluk oranları.","e2":"The house is ready for occupancy.","e2t":"Ev oturulmaya hazır."},{"w":"oceanography","tr":"okyanusbilim","te":"Noun","tt":"İsim","de":"The branch of science that deals with the physical and biological properties and phenomena of the sea","dt":"Denizlerin ve okyanusların fiziksel/biyolojik özelliklerini inceleyen bilim","e1":"Research in oceanography.","e1t":"Okyanusbilim araştırması.","e2":"Oceanographer (noun).","e2t":"Okyanusbilimci."},{"w":"octagon","tr":"sekizgen","te":"Noun","tt":"İsim","de":"A plane figure with eight straight sides and eight angles","dt":"Sekiz kenarı ve sekiz açısı olan düzlemsel şekil","e1":"The building is in the shape of an octagon.","e1t":"Bina bir sekizgen şeklindedir.","e2":"Octagonal (adjective).","e2t":"Sekizgen biçimli."},{"w":"octave","tr":"oktav / sekizli","te":"Noun","tt":"İsim","de":"A series of eight notes occupying the interval between (and including) two notes, one having twice or half the frequency of vibration of the other","dt":"Bir notadan başlayıp sekizinci notaya kadar olan müzikal aralık","e1":"To sing an octave higher.","e1t":"Bir oktav daha tizden söylemek.","e2":"An octave in poetry (first eight lines of a sonnet).","e2t":"Sekiz mısralık bent."},{"w":"offertory","tr":"sunu / ayinde toplanan bağış","te":"Noun","tt":"İsim","de":"The offering of the bread and wine for the Eucharist; or the collection of money at a Christian church service","dt":"Ayin sırasında ekmek/şarap sunulması veya toplanan bağış","e1":"To give money during the offertory.","e1t":"Bağış toplama anında para vermek.","e2":"","e2t":""},{"w":"onomatopoeia","tr":"yansıma sözcük / ses taklidi","te":"Noun","tt":"İsim","de":"The formation of a word from a sound associated with what is named","dt":"Doğadaki seslerin taklit edilmesiyle oluşan kelime (şırıl, güm, vız vb.)","e1":"\"Buzz\" and \"hiss\" are examples of onomatopoeia.","e1t":"\"Vız\" ve \"tıslama\" yansıma sözcüklere örnektir.","e2":"Onomatopoeic (adjective).","e2t":"Ses yansımalı."},{"w":"opacity","tr":"matlık / anlaşılmazlık / donukluk","te":"Noun","tt":"İsim","de":"The quality of lacking transparency or translucence; or the quality of being difficult to understand","dt":"Saydam olmama durumu; veya anlaşılmasının zor olması","e1":"The opacity of the glass.","e1t":"Camın matlığı (saydam olmaması).","e2":"The opacity of his writing style.","e2t":"Yazı tarzının kapalılığı (anlaşılmazlığı)."},{"w":"opined","tr":"görüş bildirmek / iddia etmek","te":"Verb","tt":"Fiil","de":"State or hold as an opinion","dt":"Bir görüşü dile getirmek veya bir fikre sahip olmak","e1":"He opined that the project would fail.","e1t":"Projenin başarısız olacağı yönünde görüş bildirdi.","e2":"Opine (verb).","e2t":"Fikir beyan etmek."},{"w":"oration","tr":"nutuk / tören konuşması","te":"Noun","tt":"İsim","de":"A formal speech, especially one given on a ceremonial occasion","dt":"Özellikle resmi törenlerde yapılan etkileyici ve uzun konuşma","e1":"He delivered a moving funeral oration.","e1t":"Dokunaklı bir cenaze nutku çekti.","e2":"Orator (noun).","e2t":"Hatip / Konuşmacı."},{"w":"orb","tr":"küre / gök cismi / saltanat küresi","te":"Noun","tt":"İsim","de":"A spherical body; or a golden ball topped by a cross as a symbol of monarchical power","dt":"Küre şeklinde nesne; veya hükümdarlık sembolü olan altın küre","e1":"The glowing orb of the sun.","e1t":"Güneşin parlayan küresi.","e2":"The king held the orb and scepter.","e2t":"Kral küre ve asayı tuttu."},{"w":"orchard","tr":"meyve bahçesi","te":"Noun","tt":"İsim","de":"A piece of land planted with fruit trees","dt":"Meyve ağaçlarının dikili olduğu arazi","e1":"An apple orchard.","e1t":"Elma bahçesi.","e2":"Walking through the cherry orchards.","e2t":"Kiraz bahçelerinde yürümek."},{"w":"orchestrate","tr":"orkestraya uyarlamak / (gizlice) düzenlemek","te":"Verb","tt":"Fiil","de":"Arrange or score (music) for orchestral performance; or to plan or coordinate something elements","dt":"Müziği orkestra için düzenlemek; veya (mecazi) karmaşık bir olayı gizlice planlayıp yönetmek","e1":"To orchestrate a coup.","e1t":"Bir darbe tezgahlamak (organize etmek).","e2":"The whole event was carefully orchestrated.","e2t":"Tüm olay dikkatle koordine edilmişti."},{"w":"ordnance","tr":"askeri mühimmat / ağır silahlar","te":"Noun","tt":"İsim","de":"Mounted guns; artillery; or military supplies including weapons and ammunition","dt":"Toplar, ağır silahlar veya her türlü askeri mühimmat","e1":"An ordnance depot.","e1t":"Mühimmat deposu.","e2":"Unexploded ordnance (UXO).","e2t":"Patlamamış mühimmat."},{"w":"orthography","tr":"yazım kuralları / imla","te":"Noun","tt":"İsim","de":"The conventional spelling system of a language","dt":"Bir dilin doğru yazılış kuralları ve imlası","e1":"English orthography is often difficult.","e1t":"İngilizcenin yazım kuralları genellikle zordur.","e2":"Orthographic (adjective).","e2t":"Yazımla ilgili."},{"w":"pachyderm","tr":"kalın derili hayvan (fil/gergedan vb.)","te":"Noun","tt":"İsim","de":"A very large mammal with thick skin, especially an elephant, rhinoceros, or hippopotamus","dt":"Fil, gergedan veya su aygırı gibi kalın derili ve iri yapılı hayvan","e1":"Elephants are the most famous pachyderms.","e1t":"Filler en meşhur kalın derili hayvanlardır.","e2":"(Not: Mecazi olarak \"vurdumduymaz/duygusuz kişi\" için de kullanılır).","e2t":""},{"w":"palate","tr":"damak / tat alma duyusu","te":"Noun","tt":"İsim","de":"The roof of the mouth; or a person's appreciation of taste and flavor","dt":"Ağzın tavanı (damak); veya birinin yemeklerdeki lezzet seçiciliği","e1":"Hard and soft palate.","e1t":"Sert ve yumuşak damak.","e2":"To satisfy a sophisticated palate.","e2t":"Seçici bir damak tadını memnun etmek."},{"w":"paleontology","tr":"paleontoloji / fosil bilim","te":"Noun","tt":"İsim","de":"The branch of science concerned with fossil animals and plants","dt":"Fosil hayvan ve bitkileri inceleyen bilim dalı","e1":"A degree in paleontology.","e1t":"Paleontoloji diploması.","e2":"Paleontologist (noun).","e2t":"Paleontolog."},{"w":"palisade","tr":"çit / parmaklık / kazık saplı duvar","te":"Noun/Verb","tt":"İsim/Fiil","de":"A fence of wooden stakes or iron railings fixed in the ground, forming an enclosure or defense","dt":"Savunma amacıyla yere dikilen sivri uçlu kazıklardan oluşan çit","e1":"A defensive palisade.","e1t":"Savunma amaçlı kazıklı çit.","e2":"The village was surrounded by a palisade.","e2t":"Köy, kazıklı bir duvarla çevriliydi."},{"w":"palliative","tr":"hafifletici / dindirici / geçici çözüm","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a medicine or medical care) relieving pain without dealing with the cause of the condition","dt":"Nedeni ortadan kaldırmadan sadece acıyı dindiren (ilaç/bakım)","e1":"Palliative treatment.","e1t":"Belirtileri dindirmeye yönelik tedavi.","e2":"Palliative measures.","e2t":"Geçici (hafifletici) önlemler."},{"w":"pang","tr":"ani acı / sızı / sancı","te":"Noun","tt":"İsim","de":"A sudden sharp pain or painful emotion","dt":"Hem fiziksel hem de duygusal olarak hissedilen ani ve keskin acı","e1":"A pang of hunger.","e1t":"Ani bir açlık sancısı.","e2":"A pang of guilt.","e2t":"Ani bir suçluluk sızısı (duygusu)."},{"w":"panoramic","tr":"panoramik / kuşbakışı ve geniş","te":"Adjective","tt":"Sıfat","de":"(Of a view) including all or many aspects of something; wide","dt":"Çok geniş bir alanı gören; her şeyi kapsayan","e1":"A panoramic view of the city.","e1t":"Şehrin panoramik (geniş açılı) manzarası.","e2":"Panorama (noun).","e2t":"Genel görünüm."},{"w":"parchment","tr":"parşömen / deri kağıt","te":"Noun","tt":"İsim","de":"A stiff, flat, thin material made from the prepared skin of an animal and used as a durable surface for writing","dt":"Yazı yazmak için hazırlanan hayvan derisi","e1":"An old parchment document.","e1t":"Eski bir parşömen belgesi.","e2":"","e2t":""},{"w":"pare","tr":"yontmak / (kabuğunu) soymak / azaltmak","te":"Verb","tt":"Fiil","de":"Trim (something) by cutting away its outer edges; or gradually reduce (something)","dt":"Dış kısımlarını keserek küçültmek; veya masrafları vb. kısmak","e1":"To pare an apple.","e1t":"Elma soymak.","e2":"The budget has been pared down to the minimum.","e2t":"Bütçe minimuma indirildi (kısıldı)."},{"w":"parquet","tr":"parke / yer döşemesi","te":"Noun/Verb","tt":"İsim/Fiil","de":"Flooring composed of wooden blocks arranged in a geometric pattern","dt":"Ahşap parçalardan oluşan geometrik desenli yer döşemesi","e1":"A parquet floor.","e1t":"Parke zemin.","e2":"To lay parquet.","e2t":"Parke döşemek."},{"w":"parsimonious","tr":"aşırı tutumlu / cimri / eli sıkı","te":"Adjective","tt":"Sıfat","de":"Very unwilling to spend money or use resources","dt":"Para harcamaktan çok kaçınan (pinti)","e1":"A parsimonious employer.","e1t":"Cimri bir işveren.","e2":"Parsimony (noun).","e2t":"Cimrilik / Aşırı tutumluluk."},{"w":"pathogen","tr":"patojen / hastalık yapıcı mikroorganizma","te":"Noun","tt":"İsim","de":"A bacterium, virus, or other microorganism that can cause disease","dt":"Hastalığa neden olan her türlü bakteri, virüs veya mantar","e1":"A dangerous human pathogen.","e1t":"Tehlikeli bir insan patojeni.","e2":"Pathogenic (adjective).","e2t":"Hastalık yapıcı."},{"w":"patrimony","tr":"baba mirası / kalıtsal mülk","te":"Noun","tt":"İsim","de":"Property inherited from one's father or male ancestor","dt":"Babadan kalan miras veya mülk","e1":"To protect the national patrimony.","e1t":"Ulusal mirası korumak.","e2":"He squandered his patrimony.","e2t":"Baba mirasını çarçur etti."},{"w":"patronize","tr":"desteklemek / küçümser davranmak / müdavimi olmak","te":"Verb","tt":"Fiil","de":"Treat in a way that is apparently kind or helpful but that betrays a feeling of superiority; or to be a regular customer","dt":"Birini korur gibi yapıp aslında küçümsemek; veya bir yerin sürekli müşterisi olmak","e1":"Don't patronize me!","e1t":"Bana çocukmuşum gibi davranma (beni küçümseme)!","e2":"To patronize a local restaurant.","e2t":"Yerel bir restoranın müşterisi olmak."},{"w":"pedagogy","tr":"pedagoji / eğitim bilimi","te":"Noun","tt":"İsim","de":"The method and practice of teaching, especially as an academic subject or theoretical concept","dt":"Öğretme yöntemi ve eğitim teorisi","e1":"Innovative pedagogy.","e1t":"Yenilikçi pedagoji (eğitim yöntemi).","e2":"Pedagogical (adjective).","e2t":"Eğitsel."},{"w":"pedantic","tr":"bilgiçlik taslayan / kılı kırk yaran","te":"Adjective","tt":"Sıfat","de":"Excessively concerned with minor details or rules; over","dt":"scrupulous","e1":"Kurallara veya ufak detaylara aşırı takılan","e1t":"A pedantic teacher.","e2":"Kuralcı ve ayrıntıcı bir öğretmen.","e2t":"A pedantic description."},{"w":"peddle","tr":"seyyar satıcılık yapmak / (dedikodu/fikir) yaymak","te":"Verb","tt":"Fiil","de":"Try to sell (something, especially small goods) by going from house to house or place to place; or to promote an idea","dt":"Kapı kapı dolaşarak bir şey satmak; veya bir fikri/dedikoduyu yaymaya çalışmak","e1":"To peddle drugs.","e1t":"Uyuşturucu satmak (torbacılık yapmak).","e2":"To peddle influence.","e2t":"Nüfuz ticareti yapmak."},{"w":"pedestal","tr":"kaide / ayaklık / kürsü","te":"Noun","tt":"İsim","de":"The base or support on which a statue, obelisk, or column is mounted","dt":"Heykel veya sütun tabanı","e1":"To place a statue on a pedestal.","e1t":"Bir heykeli kaide üzerine oturtmak.","e2":"To put someone on a pedestal (birini gözünde çok yüceltmek).","e2t":""},{"w":"peevish","tr":"huysuz / asabi / mızmız","te":"Adjective","tt":"Sıfat","de":"Easily irritated, especially by unimportant things","dt":"Küçük şeylere kolayca sinirlenen (aksi)","e1":"A peevish child.","e1t":"Mızmız bir çocuk.","e2":"To be in a peevish mood.","e2t":"Huysuz bir ruh halinde olmak."},{"w":"pendent","tr":"sarkan / asılı / henüz sonuçlanmamış","te":"Adjective","tt":"Sıfat","de":"Hanging down; or remaining undecided","dt":"Aşağı sarkan; veya (hukukta) henüz karara bağlanmamış","e1":"Pendent willow branches.","e1t":"Aşağı sarkan salkım söğüt dalları.","e2":"Pendent litigation (devam eden dava).","e2t":""},{"w":"pendulum","tr":"sarkaç / pandül","te":"Noun","tt":"İsim","de":"A weight hung from a fixed point so that it can swing freely backward and forward","dt":"Bir noktadan asılı durup sallanan ağırlık","e1":"The swinging of a pendulum.","e1t":"Bir sarkacın sallanışı.","e2":"The pendulum of public opinion.","e2t":"Kamuoyunun (bir o yana bir bu yana giden) değişkenliği."},{"w":"penetrable","tr":"nüfuz edilebilir / girilebilir / anlaşılabilir","te":"Adjective","tt":"Sıfat","de":"Allowing something to pass through; or capable of being understood","dt":"İçinden geçilebilen veya zihnen kavranabilen","e1":"A penetrable barrier.","e1t":"Geçit veren (aşılabilir) bir engel.","e2":"(Not: Impenetrable","e2t":"girilemez/anlaşılamaz"},{"w":"penumbra","tr":"yarı gölge","te":"Noun","tt":"İsim","de":"The partially shaded outer region of the shadow cast by an opaque object","dt":"Bir gölgenin etrafındaki daha hafif gölgeli alan","e1":"In the penumbra of the eclipse.","e1t":"Tutulmanın yarı gölge alanında.","e2":"(Mecazi) Belirsiz sınır bölgesi.","e2t":""},{"w":"penurious","tr":"meteliksiz / çok fakir / cimri","te":"Adjective","tt":"Sıfat","de":"Extremely poor; poverty","dt":"stricken; or parsimonious","e1":"Çok yoksul; veya (mecazi) çok cimri","e1t":"A penurious life.","e2":"Yoksulluk içinde bir hayat.","e2t":"Penury (noun)."},{"w":"peon","tr":"amele / düşük seviyeli işçi / piyade","te":"Noun","tt":"İsim","de":"A person who does low","dt":"level and unskilled work","e1":"Vasıfsız ve düşük ücretli çalışan (ayak işlerine bakan)","e1t":"I'm just a peon in this company.","e2":"Bu şirkette sadece düşük seviyeli bir çalışanım.","e2t":""},{"w":"perigee","tr":"yerberi noktası","te":"Noun","tt":"İsim","de":"The point in the orbit of the moon or a satellite at which it is nearest to the earth","dt":"Ay veya bir uydunun dünya etrafındaki yörüngesinde dünyaya en yakın olduğu nokta","e1":"The moon reaches its perigee today.","e1t":"Ay bugün yerberi noktasına (dünyaya en yakın konuma) ulaşıyor.","e2":"","e2t":""},{"w":"perilous","tr":"çok tehlikeli / riskli","te":"Adjective","tt":"Sıfat","de":"Full of danger or risk","dt":"Büyük tehlikelerle dolu olan","e1":"A perilous journey across the mountains.","e1t":"Dağlar üzerinden yapılan tehlikeli bir yolculuk.","e2":"The situation is becoming increasingly perilous.","e2t":"Durum giderek daha riskli bir hal alıyor."},{"w":"periodic","tr":"periyodik / devirli / düzenli aralıklarla olan","te":"Adjective","tt":"Sıfat","de":"Appearing or occurring at intervals","dt":"Belirli zaman aralıklarıyla tekrarlanan","e1":"Periodic visits.","e1t":"Düzenli aralıklarla yapılan ziyaretler.","e2":"Periodic table (chemistry).","e2t":"Periyodik tablo."},{"w":"peripatetic","tr":"gezgin / seyyar / dolaşan","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Traveling from place to place, in particular working or based in various places for relatively short periods","dt":"İş gereği sürekli yer değiştiren (gezici)","e1":"A peripatetic music teacher.","e1t":"Okul okul gezen bir müzik öğretmeni.","e2":"Peripatetic lifestyle.","e2t":"Gezgin yaşam tarzı. (Not: Aristoteles'in yürüyerek ders anlatan öğrencileri için de kullanılır)."},{"w":"peroration","tr":"nutuk sonu / özet konuşma","te":"Noun","tt":"İsim","de":"The concluding part of a speech, typically intended to inspire enthusiasts","dt":"Bir konuşmanın dinleyicileri etkilemek için yapılan coşkulu bitiş bölümü","e1":"He ended his speech with a long peroration.","e1t":"Konuşmasını uzun ve etkili bir bitiş nutkuyla tamamladı.","e2":"","e2t":""},{"w":"perpetual","tr":"sürekli / ebedi / bitmek bilmeyen","te":"Adjective","tt":"Sıfat","de":"Never ending or changing; occurring repeatedly","dt":"Hiç bitmeyen, kalıcı veya sürekli tekrarlanan","e1":"Perpetual motion.","e1t":"Sürekli hareket.","e2":"A perpetual problem.","e2t":"Bitmek bilmeyen bir sorun."},{"w":"perquisite","tr":"imtiyaz / yan hak / avanta","te":"Noun","tt":"İsim","de":"A thing regarded as a special right or privilege enjoyed as a result of one's position","dt":"Mevki veya iş gereği sahip olunan özel hak (genellikle kısalmış hali 'perk' kullanılır)","e1":"Company cars are a perquisite of the job.","e1t":"Şirket arabaları bu işin bir ek getirisidir (imtiyazıdır).","e2":"The perquisites of power.","e2t":"Gücün getirdiği ayrıcalıklar."},{"w":"personify","tr":"kişileştirmek / temsil etmek / canlı örneği olmak","te":"Verb","tt":"Fiil","de":"Represent (a quality or concept) by a figure in human form; or to be a perfect example of","dt":"Bir kavramı insan formunda temsil etmek; veya bir niteliğin canlı timsali olmak","e1":"To personify justice.","e1t":"Adaleti kişileştirmek.","e2":"She personifies elegance.","e2t":"O, zarafetin vücut bulmuş halidir."},{"w":"perspicuity","tr":"açıklık / netlik / anlaşılırlık","te":"Noun","tt":"İsim","de":"The quality of being expressed clearly; lucidity","dt":"(Yazı veya söz için) çok açık ve anlaşılır olma durumu","e1":"The perspicuity of his argument.","e1t":"Argümanının netliği (anlaşılırlığı).","e2":"To write with perspicuity.","e2t":"Açık ve net bir şekilde yazmak."},{"w":"pert","tr":"küstah / şuh / kendine güvenen","te":"Adjective","tt":"Sıfat","de":"(Of a girl or young woman) impudent or cheeky; or (of a body part) small and attractive","dt":"(Genç kadın için) küstah ama çekici; veya dik ve düzgün","e1":"A pert answer.","e1t":"Küstahça bir cevap.","e2":"Her pert nose.","e2t":"Onun küçük ve kalkık (dik) burnu."},{"w":"pertain","tr":"ilgili olmak / ait olmak","te":"Verb","tt":"Fiil","de":"Be appropriate, related, or applicable","dt":"Bir konuyla ilgili olmak veya bir şeye mahsus olmak","e1":"These rules pertain to all students.","e1t":"Bu kurallar tüm öğrenciler için geçerlidir (onlarla ilgilidir).","e2":"Matters pertaining to the environment.","e2t":"Çevreye dair (ilgili) konular."},{"w":"pertinacious","tr":"inatçı / ısrarcı / vazgeçmeyen","te":"Adjective","tt":"Sıfat","de":"Holding firmly to an opinion or a course of action","dt":"Bir fikirde veya yolda inatla (vazgeçmeden) devam eden","e1":"A pertinacious salesman.","e1t":"Israrcı bir satıcı.","e2":"She was pertinacious in her search for the truth.","e2t":"Gerçeği arama konusunda çok azimli (inatçı) idi."},{"w":"perturb","tr":"huzursuz etmek / kafasını karıştırmak / (yörüngeyi) bozmak","te":"Verb","tt":"Fiil","de":"Make (someone) anxious or unsettled; or to subject to a small disturbance","dt":"Birini endişelendirmek veya düzenini bozmak","e1":"She was perturbed by the news.","e1t":"Haberler onu huzursuz etti.","e2":"To perturb a system.","e2t":"Bir sistemi (veya yörüngeyi) bozmak (sarsmak)."},{"w":"peruse","tr":"dikkatle okumak / incelemek","te":"Verb","tt":"Fiil","de":"Read (something), typically in a thorough or careful way","dt":"Bir metni veya belgeyi başından sonuna dikkatle incelemek","e1":"To peruse the contract.","e1t":"Sözleşmeyi dikkatle okumak.","e2":"Perusal (noun).","e2t":"İnceleme / Okuma."},{"w":"perverse","tr":"aksi / ters / sapkın / bile bile yanlış yapan","te":"Adjective","tt":"Sıfat","de":"Showing a deliberate and obstinate desire to behave in a way that is unreasonable or unacceptable","dt":"Bilerek mantıksız davranan (ters); veya ahlaken çarpık","e1":"A perverse sense of humor.","e1t":"Çarpık (garip) bir mizah anlayışı.","e2":"For some perverse reason, he refused to help.","e2t":"Garip (aksi) bir nedenle yardım etmeyi reddetti."},{"w":"perversion","tr":"çarpıklık / sapkınlık / yozlaşma","te":"Noun","tt":"İsim","de":"The alteration of something from its original course, meaning, or state to a distortion or corruption or something","dt":"Bir şeyin aslından saptırılması (yozlaşma); veya cinsel sapkınlık","e1":"A perversion of justice.","e1t":"Adaletin saptırılması (yerini bulmaması).","e2":"Sexual perversion.","e2t":"Cinsel sapkınlık."},{"w":"pestilence","tr":"veba / salgın hastalık / bela","te":"Noun","tt":"İsim","de":"A fatal epidemic disease, especially bubonic plague","dt":"Ölümcül salgın hastalık; veya (mecazi) toplumsal bela","e1":"To survive the pestilence.","e1t":"Salgın hastalıktan sağ çıkmak.","e2":"Pestilential (adjective).","e2t":"Salgın gibi / Zararlı."},{"w":"pestle","tr":"havan eli","te":"Noun","tt":"İsim","de":"A heavy tool with a rounded end, used for crushing and grinding substances in a mortar","dt":"Havanda bir şeyleri ezmek için kullanılan tokmak","e1":"To grind spices with a mortar and pestle.","e1t":"Baharatları havan ve havan eliyle dövmek.","e2":"","e2t":""},{"w":"petrify","tr":"taşlaşmak / donakalmak (korkudan)","te":"Verb","tt":"Fiil","de":"Make (someone) so frightened that they are unable to move; or change into a stony substance","dt":"Korkudan kaskatı kesilmek; veya mineralleşerek taş haline gelmek","e1":"I was petrified with fear.","e1t":"Korkudan donakaldım (taş kesildim).","e2":"Petrified wood.","e2t":"Taşlaşmış ağaç (fosil)."},{"w":"petulant","tr":"huysuz / asabi / çocuk gibi küsen","te":"Adjective","tt":"Sıfat","de":"(Of a person or their manner) childishly sulky or bad","dt":"tempered","e1":"Çocuksu bir şekilde hırçın ve somurtkan","e1t":"A petulant child.","e2":"Huysuz bir çocuk.","e2t":"He made a petulant remark."},{"w":"phantom","tr":"hayalet / hayal / görüntü","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A ghost; or a figment of the imagination","dt":"Hayalet; veya sadece zihinde var olan görüntü/sanrı","e1":"The phantom of the opera.","e1t":"Operadaki hayalet.","e2":"Phantom pain (medicine).","e2t":"Ampute edilen uzuvda hissedilen hayalet ağrı."},{"w":"philander","tr":"hovardalık yapmak / kadınlarla oynaşmak","te":"Verb","tt":"Fiil","de":"(Of a man) readily or frequently enter into casual sexual relationships with women","dt":"(Erkek için) gönül eğlendirmek, kadınlarla flört etmek","e1":"He was known to philander.","e1t":"Hovardalığıyla bilinirdi.","e2":"Philanderer (noun).","e2t":"Hovarda / Çapkın."},{"w":"philanthropist","tr":"hayırsever","te":"Noun","tt":"İsim","de":"A person who seeks to promote the welfare of others, especially by the generous donation of money to good causes","dt":"Özellikle büyük bağışlar yaparak insanlığa hizmet eden kişi","e1":"A wealthy philanthropist.","e1t":"Zengin bir hayırsever.","e2":"Philanthropy (noun).","e2t":"Hayırseverlik."},{"w":"philatelist","tr":"filatelist / pul koleksiyoncusu","te":"Noun","tt":"İsim","de":"A person who collects or studies postage stamps","dt":"Posta pulları biriktiren veya inceleyen uzman","e1":"My uncle is a keen philatelist.","e1t":"Amcam meraklı bir pul koleksiyoncusudur.","e2":"Philately (noun).","e2t":"Pulculuk."},{"w":"philistine","tr":"sanattan anlamayan / dar kafalı / filistinli","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who is hostile or indifferent to culture and the arts","dt":"Kültür ve sanata karşı ilgisiz veya düşmanca davranan (estetikten yoksun) kişi","e1":"I am a bit of a philistine when it comes to opera.","e1t":"Opera konusunda biraz zevksiz (cahil) sayılırım.","e2":"(Not: Antik Filist halkından gelir).","e2t":""},{"w":"philology","tr":"filoloji / dilbilim / dil incelemesi","te":"Noun","tt":"İsim","de":"The branch of knowledge that deals with the structure, historical development, and relationships of a language","dt":"Dillerin yapısını ve tarihsel gelişimini inceleyen bilim","e1":"Comparative philology.","e1t":"Karşılaştırmalı filoloji.","e2":"Philologist (noun).","e2t":"Dil bilimci."},{"w":"phlegmatic","tr":"soğukkanlı / ağırkanlı / duygusuz","te":"Adjective","tt":"Sıfat","de":"(Of a person) having an unemotional and stolidly calm disposition","dt":"Olaylar karşısında sakinliğini koruyan, heyecanlanmayan (ağırbaşlı)","e1":"A phlegmatic approach to the crisis.","e1t":"Krize karşı soğukkanlı bir yaklaşım.","e2":"He is remarkably phlegmatic.","e2t":"Şaşırtıcı derecede sakindir. (Not: İsmini antik tıp kuramındaki 'balgam'"},{"w":"phobia","tr":"fobi / aşırı korku","te":"Noun","tt":"İsim","de":"An extreme or irrational fear of or aversion to something","dt":"Bir şeye karşı duyulan aşırı ve mantıksız korku","e1":"To have a phobia about spiders.","e1t":"Örümcek fobisi olmak.","e2":"Social phobia.","e2t":"Sosyal fobi."},{"w":"phoenix","tr":"anka kuşu / föniks","te":"Noun","tt":"İsim","de":"(In classical mythology) a unique bird that burned itself on a funeral pyre and rose from the ashes with renewed youth","dt":"Küllerinden yeniden doğduğuna inanılan efsanevi kuş","e1":"To rise like a phoenix from the ashes.","e1t":"Küllerinden bir anka kuşu gibi doğmak (yeniden canlanmak).","e2":"","e2t":""},{"w":"phonetics","tr":"fonetik / ses bilgisi","te":"Noun","tt":"İsim","de":"The study and classification of speech sounds","dt":"Konuşma seslerini ve özelliklerini inceleyen bilim","e1":"The phonetics of the English language.","e1t":"İngilizce fonetiği.","e2":"Phonetic spelling.","e2t":"Okunduğu gibi yazma."},{"w":"phosphorescence","tr":"fosfor ışığı / yakamoz","te":"Noun","tt":"İsim","de":"Light emitted by a substance without combustion or perceptible heat","dt":"Bir maddenin ısı yaymadan ışık saçması; soğuk ışık","e1":"The phosphorescence of the sea at night.","e1t":"Gece denizde oluşan yakamoz (fosfor ışıltısı).","e2":"Glow","e2t":"in"},{"w":"photogenic","tr":"fotojenik / fotoğrafta güzel çıkan","te":"Adjective","tt":"Sıfat","de":"(Especially of a person) looking attractive in photographs","dt":"Fotoğraflarda gerçekte olduğundan daha güzel veya etkileyici görünen","e1":"She is very photogenic.","e1t":"O çok fotojenik biridir.","e2":"A photogenic city.","e2t":"Fotoğraf çekmeye çok uygun (görseli zengin) şehir."},{"w":"phraseology","tr":"ifade tarzı / deyimleme","te":"Noun","tt":"İsim","de":"A particular mode of expression, especially one characteristic of a particular speaker or subject","dt":"Belirli bir konuya veya kişiye özgü seçilen kelimeler ve ifade biçimi","e1":"Legal phraseology.","e1t":"Hukuki ifade tarzı.","e2":"The peculiar phraseology of the document.","e2t":"Belgenin kendine has (alışılmadık) dili."},{"w":"physiognomy","tr":"yüz hatları / sima","te":"Noun","tt":"İsim","de":"A person's facial features or expression, especially when regarded as indicative of character","dt":"Özellikle karakterin aynası olduğu düşünülen yüz hatları","e1":"He has a striking physiognomy.","e1t":"Dikkat çekici bir yüz yapısı (sima) var.","e2":"To study someone's physiognomy.","e2t":"Birinin simasını incelemek."},{"w":"physiological","tr":"fizyolojik","te":"Adjective","tt":"Sıfat","de":"Relating to the branch of biology that deals with the normal functions of living organisms and their parts","dt":"Canlıların hayati işlevleri ve işleyişi ile ilgili","e1":"Physiological changes during exercise.","e1t":"Egzersiz sırasında meydana gelen fizyolojik değişimler.","e2":"A physiological reaction to stress.","e2t":"Stres karşısında verilen fizyolojik tepki."},{"w":"picaresque","tr":"pikaresk / serüven dolu (roman)","te":"Adjective","tt":"Sıfat","de":"Relating to an episodic style of fiction dealing with the adventures of a rough and dishonest but appealing hero","dt":"Dürüst olmayan ama sempatik bir kahramanın maceralarını anlatan roman tarzı","e1":"A picaresque novel.","e1t":"Pikaresk roman.","e2":"The film has a picaresque quality.","e2t":"Filmin macera dolu (pikaresk) bir havası var."},{"w":"piebald","tr":"alaca / siyah beyaz lekeli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a horse) having irregular patches of two colors, typically black and white","dt":"Özellikle siyah ve beyaz lekeleri olan (genellikle atlar için)","e1":"A piebald pony.","e1t":"Alaca bir midilli.","e2":"","e2t":""},{"w":"pinnacle","tr":"zirve / doruk / kulecik","te":"Noun","tt":"İsim","de":"The most successful point; the culmination; or a high, pointed piece of rock","dt":"Başarının en üst noktası; veya sarp kaya doruğu; veya küçük kule","e1":"At the pinnacle of her career.","e1t":"Kariyerinin zirvesinde.","e2":"The pinnacles of the cathedral.","e2t":"Katedralin ince kulecikleri."},{"w":"pivotal","tr":"çok önemli / merkezi / hayati","te":"Adjective","tt":"Sıfat","de":"Of crucial importance in relation to the development or success of something","dt":"Bir şeyin başarısında veya gelişiminde kilit rol oynayan","e1":"A pivotal moment in history.","e1t":"Tarihin dönüm noktası (çok önemli bir anı).","e2":"He played a pivotal role in the negotiations.","e2t":"Müzakerelerde kilit bir rol oynadı."},{"w":"plait","tr":"örgü / saç örgüsü / örmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A single length of hair or other flexible material made up of three or more interlaced strands","dt":"Saç veya ip örgüsü; veya (fiil) örmek","e1":"She wore her hair in long plaits.","e1t":"Saçlarını uzun örgüler yapmıştı.","e2":"To plait a rope.","e2t":"Bir halatı örmek."},{"w":"plebiscite","tr":"plebisit / halk oylaması","te":"Noun","tt":"İsim","de":"The direct vote of all the members of an electorate on an important public question such as a change in the constitution","dt":"Önemli bir devlet meselesinde halkın doğrudan oyuna başvurulması","e1":"To hold a plebiscite on independence.","e1t":"Bağımsızlık konusunda halk oylaması yapmak.","e2":"(Not: Referendum ile benzerdir).","e2t":""},{"w":"poised","tr":"hazır / nazır / dengeli / vakur","te":"Adjective","tt":"Sıfat","de":"Having a composed and self","dt":"assured manner; or ready for action","e1":"Kendinden emin ve sakin; veya harekete geçmeye hazır","e1t":"She looked calm and poised.","e2":"Sakin ve vakur (kendinden emin) görünüyordu.","e2t":"The army is poised for attack."},{"w":"polarize","tr":"kutuplaştırmak / zıtlaştırmak","te":"Verb","tt":"Fiil","de":"Restrict the vibrations of (a transverse wave, especially light) wholly or partially to one direction; or to divide into two sharply contrasting groups","dt":"(Işığı) kutuplaştırmak; veya toplumun iki zıt gruba bölünmesine yol açmak","e1":"The issue has polarized the nation.","e1t":"Bu mesele ulusu kutuplaştırdı.","e2":"Polarized sunglasses.","e2t":"Polarize güneş gözlüğü."},{"w":"polyglot","tr":"çok dilli","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Knowing or using several languages","dt":"Birkaç dil bilen veya birkaç dilden oluşan","e1":"A polyglot community.","e1t":"Çok dilli bir topluluk.","e2":"He is a true polyglot, speaking six languages fluently.","e2t":"Altı dili akıcı konuşan gerçek bir çok dillidir."},{"w":"pomposity","tr":"şatafat / kendini beğenmişlik / kurumluluk","te":"Noun","tt":"İsim","de":"The quality of being pompous; self","dt":"importance","e1":"Aşırı ciddi ve kendini üstün gören tavır","e1t":"He was annoyed by the professor's pomposity.","e2":"Profesörün kendini beğenmişliği onu rahatsız etti.","e2t":"Pompous (adjective)."},{"w":"pontificate","tr":"ahkam kesmek / papa gibi konuşmak","te":"Verb","tt":"Fiil","de":"Express one's opinions in a way considered annoyingly dogmatic","dt":"Kendi görüşlerini sanki tek doğruymuş gibi (bilgiçlik taslayarak) anlatmak","e1":"He is always pontificating about politics.","e1t":"Siyaset hakkında sürekli ahkam kesiyor.","e2":"Pontiff (noun).","e2t":"Papa."},{"w":"predatory","tr":"yırtıcı / avcı / yağmacı","te":"Adjective","tt":"Sıfat","de":"Relating to or denoting an animal or animals preying naturally on others; or seeking to exploit others","dt":"Avlanarak beslenen (hayvan); veya (mecazi) başkalarını sömüren/yağmalayan","e1":"Predatory animals like wolves.","e1t":"Kurtlar gibi yırtıcı hayvanlar.","e2":"Predatory pricing (economics).","e2t":"Yıkıcı fiyatlandırma (rakipleri yok etmek için)."},{"w":"predestination","tr":"kader / alın yazısı","te":"Noun","tt":"İsim","de":"(In theology) the divine foreordaining of all that will happen, especially with regard to the salvation of some and not others","dt":"Her şeyin önceden Tanrı tarafından belirlenmiş olması inancı","e1":"To believe in predestination.","e1t":"Kadere (alın yazısına) inanmak.","e2":"Predestine (verb).","e2t":"Alın yazısını belirlemek."},{"w":"prefect","tr":"sınıf başkanı / emniyet müdürü / vali (bazı ülkelerde)","te":"Noun","tt":"İsim","de":"A senior pupil who is given certain powers of discipline; or a chief officer","dt":"Disiplini sağlamakla görevli kıdemli öğrenci; veya bölge yöneticisi","e1":"A school prefect.","e1t":"Okul başkanı (mümessili).","e2":"The Prefect of Police.","e2t":"Emniyet Müdürü."},{"w":"prefigure","tr":"önceden belirtmek / habercisi olmak","te":"Verb","tt":"Fiil","de":"Be an early indication or version of (something future)","dt":"Gelecekteki bir olayın ön belirtisi veya habercisi olmak","e1":"His early poems prefigure his later themes.","e1t":"İlk şiirleri, sonraki temalarının habercisidir.","e2":"Prefiguration (noun).","e2t":"Önceden canlandırma."},{"w":"prehistoric","tr":"tarih öncesi","te":"Adjective","tt":"Sıfat","de":"Relating to or denoting the period before written records","dt":"Yazılı tarihten önceki döneme ait","e1":"Prehistoric animals.","e1t":"Tarih öncesi hayvanlar.","e2":"Prehistoric cave paintings.","e2t":"Tarih öncesi mağara resimleri."},{"w":"primacy","tr":"öncelik / üstünlük / başpiskoposluk","te":"Noun","tt":"İsim","de":"The state of being first in importance; or the office of a primate (bishop)","dt":"Önem bakımından ilk sırada olma; veya en üst rütbe","e1":"To give primacy to economic issues.","e1t":"Ekonomik meselelere öncelik vermek.","e2":"The primacy of the Pope.","e2t":"Papa'nın üstünlüğü (liderliği)."},{"w":"primogeniture","tr":"büyük çocuk olma hakkı / veraset (büyük çocuk)","te":"Noun","tt":"İsim","de":"The state of being the firstborn child; or the right of succession belonging to the firstborn child","dt":"İlk doğan çocuk olma durumu veya mirasın en büyük çocuğa kalması kuralı","e1":"The law of primogeniture.","e1t":"Mirasın büyük oğula kalması yasası.","e2":"","e2t":""},{"w":"primp","tr":"süslenmek / aynanın önünde vakit geçirmek","te":"Verb","tt":"Fiil","de":"Spend time making minor adjustments to one's hair, makeup, or clothes","dt":"Giyimine veya makyajına aşırı özen göstererek (vakit harcayarak) hazırlanmak","e1":"She spent hours primping in front of the mirror.","e1t":"Aynanın önünde saatlerce süslendi.","e2":"(Bkz: Preen).","e2t":""},{"w":"privy","tr":"haberdar / gizli tutulan / dışarıdaki tuvalet","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Sharing in the knowledge of (something secret or private)","dt":"Gizli bir konuya vakıf olan (haberdar); veya gizli","e1":"I was not privy to their discussions.","e1t":"Tartışmalarından haberim yoktu (dahil edilmedim).","e2":"Privy Council.","e2t":"Danışma meclisi (gizli kurul)."},{"w":"problematic","tr":"problemli / sorunlu / şüpheli","te":"Adjective","tt":"Sıfat","de":"Constituting or presenting a problem or difficulty; doubtful","dt":"Sorun yaratan, belirsiz veya çözümü güç","e1":"A problematic situation.","e1t":"Sorunlu (çetrefilli) bir durum.","e2":"The interpretation of the text is problematic.","e2t":"Metnin yorumlanması tartışmalıdır (zordur)."},{"w":"prognosticate","tr":"önceden haber vermek / tahmin etmek","te":"Verb","tt":"Fiil","de":"Foretell or prophesy (an event in the future)","dt":"Gelecekteki bir olayı belirtilere dayanarak tahmin etmek","e1":"To prognosticate the outcome of the election.","e1t":"Seçim sonuçlarını tahmin etmek.","e2":"Prognostication (noun).","e2t":"Kehanet / Tahmin."},{"w":"prohibitive","tr":"engelleyici / çok yüksek (fiyat)","te":"Adjective","tt":"Sıfat","de":"(Of a price or charge) so high as to prevent something being done or bought","dt":"Bir şeyi yapmayı veya almayı engelleyecek kadar yüksek","e1":"Prohibitive costs.","e1t":"El yakan (engelleyici düzeyde yüksek) maliyetler.","e2":"The price of the house was prohibitive.","e2t":"Evin fiyatı yanına yaklaşılmaz (çok yüksek) düzeydeydi."},{"w":"prolixity","tr":"uzun ve sıkıcılık / laf kalabalığı","te":"Noun","tt":"İsim","de":"Tedious lengthiness of spoken or written matter","dt":"Konuşma veya yazının gereksiz yere çok uzun ve sıkıcı olması","e1":"The prolixity of his legal documents.","e1t":"Hukuki belgelerinin uzunluğu ve sıkıcılığı.","e2":"Prolix (adjective).","e2t":"Çok uzun ve sıkıcı."},{"w":"prologue","tr":"önsöz / başlangıç / giriş bölümü","te":"Noun","tt":"İsim","de":"A separate introductory section of a literary or musical work","dt":"Edebi bir eserin veya oyunun giriş (başlangıç) kısmı","e1":"The prologue to the play.","e1t":"Oyunun giriş bölümü.","e2":"(Not: Epilogue","e2t":"son söz"},{"w":"propellants","tr":"itici gazlar / yakıt (roket vb.)","te":"Noun","tt":"İsim (Plural)","de":"A substance that propels something, especially an explosive charge or a fuel for a rocket","dt":"Bir mermiyi veya roketi ileri iten patlayıcı madde veya gaz","e1":"Solid rocket propellants.","e1t":"Katı roket yakıtları.","e2":"Aerosol propellants.","e2t":"Spreylerdeki itici gazlar."},{"w":"prophylactic","tr":"koruyucu (hastalık) / önleyici","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Intended to prevent disease","dt":"Hastalığı önlemek amacıyla kullanılan ilaç veya yöntem","e1":"Prophylactic treatment.","e1t":"Koruyucu (önleyici) tedavi.","e2":"A prophylactic against malaria.","e2t":"Sıtmayı önleyici ilaç."},{"w":"propulsion","tr":"itme gücü / yürütme","te":"Noun","tt":"İsim","de":"The action of driving or pushing forward","dt":"Bir cismi ileri doğru iten güç veya sistem","e1":"Jet propulsion.","e1t":"Jet itkisi.","e2":"A means of propulsion.","e2t":"Bir ilerleme (itme) aracı."},{"w":"proselytize","tr":"dinini değiştirmeye çalışmak / saflarına katmak","te":"Verb","tt":"Fiil","de":"Convert or attempt to convert (someone) from one religion, belief, or opinion to another","dt":"Birini kendi inancına veya fikrine döndürmeye çalışmak","e1":"To proselytize for a political party.","e1t":"Bir siyasi parti için taraftar toplamak.","e2":"Proselyte (noun).","e2t":"Yeni mühtedi (din değiştiren)."},{"w":"prospectus","tr":"tanıtım broşürü / izahname","te":"Noun","tt":"İsim","de":"A printed document that advertises or describes a school, commercial enterprise, etc., in order to attract customers","dt":"Bir kurumu veya yatırım fırsatını tanıtan ayrıntılı kitapçık","e1":"A college prospectus.","e1t":"Üniversite tanıtım broşürü.","e2":"To read the company's prospectus before investing.","e2t":"Yatırım yapmadan önce şirketin izahnamesini okumak."},{"w":"protagonist","tr":"başkahraman / başrol / önder","te":"Noun","tt":"İsim","de":"The leading character or one of the major characters in a drama, movie, novel, or other fictional text","dt":"Bir eserdeki ana karakter; veya bir hareketin öncüsü","e1":"The protagonist of the story.","e1t":"Hikayenin başkahramanı.","e2":"A leading protagonist of tax reform.","e2t":"Vergi reformunun önde gelen savunucusu."},{"w":"proverbial","tr":"atasözü haline gelmiş / herkesçe bilinen / dillerde gezen","te":"Adjective","tt":"Sıfat","de":"(Of a word or phrase) referred to in a proverb; or well known","dt":"Bir atasözüne konu olmuş; veya çok meşhur olduğu için herkesin dilinde olan","e1":"The proverbial needle in a haystack.","e1t":"Samanlıkta iğne aramak misali (meşhur deyimdeki gibi).","e2":"His generosity is proverbial.","e2t":"Onun cömertliği herkesçe bilinir (dillere destandır)."},{"w":"providential","tr":"takdir","te":"i ilahi / şans eseri / tam zamanında gelen","tt":"Adjective","de":"Sıfat","dt":"Occurring at a favorable time; opportune","e1":"Tam ihtiyaç duyulan anda olan (mucizevi bir şans gibi)","e1t":"A providential escape.","e2":"Mucizevi (Allah'ın yardımıyla olan) bir kurtuluş.","e2t":"Their arrival was providential."},{"w":"provocative","tr":"kışkırtıcı / tahrik edici","te":"Adjective","tt":"Sıfat","de":"Causing annoyance, anger, or another strong reaction, especially deliberately","dt":"İnsanları sinirlendiren veya heyecanlandıran (bilerek yapılan)","e1":"A provocative remark.","e1t":"Kışkırtıcı bir yorum.","e2":"Provocative clothing.","e2t":"Tahrik edici kıyafetler."},{"w":"pulverize","tr":"toz haline getirmek / un ufak etmek / mahvetmek","te":"Verb","tt":"Fiil","de":"Reduce to fine particles; or defeat utterly","dt":"Bir şeyi ezerek toz etmek; veya (mecazi) rakibi yerle bir etmek","e1":"To pulverize rocks into sand.","e1t":"Kayaları toz haline getirmek.","e2":"Our team was pulverized in the final.","e2t":"Takımımız finalde perişan edildi (ezildi)."},{"w":"pummel","tr":"yumruklamak / pataklamak","te":"Verb","tt":"Fiil","de":"Strike repeatedly with the fists","dt":"Yumruklarla sürekli vurmak (dövmek)","e1":"He pummeled his opponent.","e1t":"Rakibini yumruk yağmuruna tuttu.","e2":"The coast was pummeled by heavy waves.","e2t":"Kıyı şeridi dev dalgalarla dövüldü."},{"w":"purgatory","tr":"araf / çile / arınma yeri","te":"Noun","tt":"İsim","de":"(In Roman Catholic doctrine) a place or state of suffering inhabited by the souls of sinners who are expiating their sins before going to heaven","dt":"Günahların temizlendiği yer (araf); veya (mecazi) büyük sıkıntı çekilen yer","e1":"Getting through the airport was sheer purgatory.","e1t":"Havaalanından geçmek tam bir çileydi.","e2":"Purgatorial (adjective).","e2t":"Arafla ilgili / Acı dolu."},{"w":"puritanical","tr":"aşırı kuralcı / bağnaz / sofu","te":"Adjective","tt":"Sıfat","de":"Practicing or affecting strict religious or moral behavior","dt":"Ahlaki veya dini konularda aşırı katı ve hoşgörüsüz","e1":"A puritanical attitude toward pleasure.","e1t":"Eğlenceye karşı bağnaz bir tutum.","e2":"Puritan (noun/adj).","e2t":"Sofu / Püriten."},{"w":"pursed","tr":"büzülmüş (dudak)","te":"Adjective","tt":"Sıfat","de":"(Of lips) contracted into a tight round shape","dt":"(Genellikle hoşnutsuzluktan) sıkıca kapatılıp büzülmüş","e1":"She looked at him with pursed lips.","e1t":"Dudaklarını büzerek (hoşnutsuzlukla) ona baktı.","e2":"Purse (verb).","e2t":"Büzmek."},{"w":"pyre","tr":"odun yığını (ölü yakmak için)","te":"Noun","tt":"İsim","de":"A heap of combustible material, especially one for burning a corpse as part of a funeral ceremony","dt":"Cenaze törenlerinde cesedi yakmak için hazırlanan büyük odun yığını","e1":"A funeral pyre.","e1t":"Cenaze odunu (yığını).","e2":"","e2t":""},{"w":"quasi","tr":"","te":"imsi / sözde / sanki / yarı","tt":"Adjective/Prefix","de":"Seemingly; apparently but not really","dt":"Yarı yarıya,","e1":"e benzeyen ama tam olmayan (sözde)","e1t":"A quasi","e2":"scientific explanation.","e2t":"Yarı bilimsel (sözde bilimsel) bir açıklama."},{"w":"quaver","tr":"titremek (ses) / sekizlik nota","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Of a person's voice) shake or tremble in speaking, typically through nervousness or emotion","dt":"(Ses için) korku veya heyecandan titremek; veya sekizlik nota","e1":"Her voice quavered as she spoke.","e1t":"Konuşurken sesi titredi.","e2":"To sing with a quaver.","e2t":"Titrek bir sesle söylemek."},{"w":"query","tr":"soru / sorgu / şüphe / sorgulamak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A question, especially one expressing doubt or requesting information","dt":"Bilgi almak için sorulan soru veya duyulan şüphe","e1":"I have a query about my bill.","e1t":"Faturam hakkında bir sorum var.","e2":"To query a decision.","e2t":"Bir kararı sorgulamak (doğruluğundan şüphe etmek)."},{"w":"quotidian","tr":"günlük / alelade / her günkü","te":"Adjective","tt":"Sıfat","de":"Of or occurring every day; daily; or ordinary","dt":"Her gün yaşanan; veya (mecazi) sıradan, alışılmış","e1":"The quotidian routine of office work.","e1t":"Ofis işlerinin günlük (sıradan) rutini.","e2":"Quotidian events.","e2t":"Alelade olaylar. (Not: Mundane ile benzerdir)."},{"w":"rancid","tr":"kokmuş / bozulmuş (yağlı yiyecek)","te":"Adjective","tt":"Sıfat","de":"(Of foods containing fat or oil) smelling or tasting unpleasant as a result of being old and stale","dt":"(Yağlı gıdalar için) acımış, bozulmuş ve fena kokan","e1":"Rancid butter.","e1t":"Acımış (bozulmuş) tereyağı.","e2":"The smell of rancid oil.","e2t":"Bozulmuş yağ kokusu."},{"w":"rapture","tr":"büyük sevinç / kendinden geçme / vecd","te":"Noun","tt":"İsim","de":"A feeling of intense pleasure or joy","dt":"Çok şiddetli mutluluk veya coşku hali","e1":"To listen to music with rapture.","e1t":"Müziği büyük bir coşkuyla (kendinden geçerek) dinlemek.","e2":"Rapturous (adjective).","e2t":"Coşkulu."},{"w":"rarefied","tr":"seyrelmiş (hava) / elit / çok az kişinin anladığı","te":"Adjective","tt":"Sıfat","de":"(Of air, especially that at high altitudes) lower pressure than usual; thin; or (of a group) distant from the lives and concerns of ordinary people","dt":"Yüksek yerlerdeki düşük basınçlı (ince) hava; veya (mecazi) sadece dar bir seçkin grubun anladığı/yaşadığı","e1":"The rarefied atmosphere of the Himalayas.","e1t":"Himalayaların seyrelmiş (ince) havası.","e2":"The rarefied world of high finance.","e2t":"Üst düzey finans dünyasının o soyut ve seçkin ortamı."},{"w":"ravening","tr":"açgözlü / av peşinde olan / yırtıcı","te":"Adjective","tt":"Sıfat","de":"(Of a wild animal) extremely hungry and hunting for prey","dt":"(Vahşi hayvan için) açlıktan gözü dönmüş ve av arayan","e1":"Ravening wolves.","e1t":"Açlıktan gözü dönmüş kurtlar.","e2":"(Mecazi: Çok hırslı).","e2t":""},{"w":"ravine","tr":"yar / dar ve derin vadi","te":"Noun","tt":"İsim","de":"A deep, narrow gorge with steep sides","dt":"Genellikle içinden su geçen, çok derin ve dar vadi","e1":"The bus fell into a deep ravine.","e1t":"Otobüs derin bir yara (vadiye) yuvarlandı.","e2":"","e2t":""},{"w":"rebus","tr":"resimli bilmece","te":"Noun","tt":"İsim","de":"A puzzle in which words are represented by combinations of pictures and individual letters","dt":"Kelimelerin resim ve harflerle temsil edildiği bir tür bilmece","e1":"To solve a rebus.","e1t":"Resimli bir bilmeceyi çözmek.","e2":"","e2t":""},{"w":"rebuttal","tr":"çürütme / karşı argüman","te":"Noun","tt":"İsim","de":"A refutation or contradiction","dt":"Bir iddiayı veya suçlamayı reddetme/çürütme eylemi","e1":"To provide a formal rebuttal of the charges.","e1t":"Suçlamalara karşı resmi bir çürütme (cevap) sunmak.","e2":"Rebut (verb).","e2t":"Çürütmek / Aksini ispatlamak."},{"w":"recluse","tr":"münzevi / yalnız yaşayan kimse","te":"Noun","tt":"İsim","de":"A person who lives a solitary life and tends to avoid other people","dt":"Toplumdan kaçan ve tek başına yaşayan kişi","e1":"He became a recluse after his wife died.","e1t":"Karısı öldükten sonra münzevi (yalnız) bir hayat yaşamaya başladı.","e2":"Reclusive (adjective).","e2t":"İçe kapanık / Münzevi."},{"w":"recreant","tr":"korkak / hain / dönek","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Cowardly; or unfaithful to a belief; apostate","dt":"Korkakça davranan; veya inancına/davasına ihanet eden","e1":"A recreant knight.","e1t":"Hain (korkak) bir şövalye.","e2":"","e2t":""},{"w":"refraction","tr":"kırılma (ışık/ses)","te":"Noun","tt":"İsim","de":"The factoring of a light ray, air current, etc. when it passes from one medium to another","dt":"Işığın bir ortamdan diğerine geçerken yön değiştirmesi","e1":"The refraction of light in water.","e1t":"Işığın sudaki kırılması.","e2":"Refractive index.","e2t":"Kırılma indisi."},{"w":"refulgent","tr":"parıl parıl / parlak / görkemli","te":"Adjective","tt":"Sıfat","de":"Shining brightly","dt":"Çok parlak ve ışıltılı","e1":"Refulgent sunlight.","e1t":"Göz kamaştıran güneş ışığı.","e2":"Her refulgent beauty.","e2t":"Onun parıldayan güzelliği."},{"w":"refutation","tr":"çürütme / aksini ispatlama","te":"Noun","tt":"İsim","de":"The action of proving a statement or theory to be wrong or false","dt":"Bir iddianın veya teorinin yanlış olduğunu kanıtlama","e1":"A brilliant refutation of the theory.","e1t":"Teorinin zekice bir çürütülmesi.","e2":"Refute (verb).","e2t":"Çürütmek."},{"w":"regiment","tr":"alay (askeri) / düzene sokmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A permanent unit of an army; or to organize according to a strict system","dt":"Askeri birlik (alay); veya (fiil) birini/bir şeyi sıkı bir disipline sokmak","e1":"An infantry regiment.","e1t":"Piyade alayı.","e2":"A highly regimented school life.","e2t":"Çok disiplinli (sıkı kuralları olan) okul hayatı."},{"w":"rejoinder","tr":"cevap / karşılık / sert yanıt","te":"Noun","tt":"İsim","de":"A reply, especially a sharp or witty one","dt":"Genellikle zekice veya sert bir şekilde verilen cevap","e1":"He made a witty rejoinder.","e1t":"Zekice bir karşılık verdi.","e2":"To wait for a rejoinder.","e2t":"Bir cevap beklemek."},{"w":"repast","tr":"öğün / yemek / ziyafet","te":"Noun","tt":"İsim","de":"A meal","dt":"Yemek veya yemek vakti (resmi ve edebi bir kullanım)","e1":"A light repast.","e1t":"Hafif bir öğün.","e2":"They enjoyed a sumptuous repast.","e2t":"Mükellef bir yemeğin tadını çıkardılar."},{"w":"repellent","tr":"itici / iğrenç / kovucu","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Able to repel a particular thing; or causing disgust","dt":"İğrenç (tiksindirici); veya (mıknatıs gibi) iten; veya böcek kaçıran madde","e1":"An insect repellent.","e1t":"Böcek kovucu.","e2":"A water","e2t":"repellent fabric."},{"w":"repine","tr":"şikayet etmek / sızlanmak / hasret çekmek","te":"Verb","tt":"Fiil","de":"Feel or express discontent; fret","dt":"Memnuniyetsizlik duymak; veya kederlenip şikayet etmek","e1":"To repine at one's fate.","e1t":"Kaderine küsmek (şikayet etmek).","e2":"There is no use repining.","e2t":"Sızlanmanın bir faydası yok."},{"w":"reprise","tr":"tekrar / (müzik) ana temanın tekrarı","te":"Noun/Verb","tt":"İsim/Fiil","de":"A repeated passage in music; or a repeated performance","dt":"Bir müzik parçasında veya filmde bir bölümün tekrar edilmesi","e1":"A reprise of the opening theme.","e1t":"Açılış temasının tekrarı.","e2":"Reprise a role.","e2t":"Bir rolü tekrar oynamak."},{"w":"reproachful","tr":"sitemkar / suçlayıcı","te":"Adjective","tt":"Sıfat","de":"Expressing disapproval or disappointment","dt":"Birine sitem veya hayal kırıklığı ifade eden","e1":"A reproachful glance.","e1t":"Sitem dolu (suçlayıcı) bir bakış.","e2":"Reproachfully (adverb).","e2t":"Sitemkar bir şekilde."},{"w":"reproof","tr":"azar / sitem / kınama","te":"Noun","tt":"İsim","de":"An expression of blame or disapproval","dt":"Bir hatadan dolayı yapılan sözlü uyarı veya sitem","e1":"A look of gentle reproof.","e1t":"Nazik bir sitem (uyarı) bakışı.","e2":"Reprove (verb).","e2t":"Azarlamak / Sitem etmek."},{"w":"repugnance","tr":"iğrenme / nefret / zıtlık","te":"Noun","tt":"İsim","de":"Intense disgust; or inconsistency or incompatibility of ideas or statements","dt":"Bir şeye karşı duyulan şiddetli tiksinti; veya fikirler arasındaki uyumsuzluk","e1":"To feel a deep repugnance for violence.","e1t":"Şiddete karşı derin bir tiksinti duymak.","e2":"Repugnant (adjective).","e2t":"İğrenç / Tiksindirici."},{"w":"repute","tr":"itibar / şöhret / saymak","te":"Noun/Verb","tt":"İsim/Fiil","de":"The opinion generally held of someone or something; the state of being generally regarded in a particular way","dt":"Birinin veya bir şeyin genel olarak nasıl bilindiği (ün)","e1":"A man of good repute.","e1t":"İyi şöhretli (saygın) bir adam.","e2":"He is reputed to be a billionaire.","e2t":"Milyarder olduğu söyleniyor (biliniyor)."},{"w":"resilience","tr":"direnç / esneklik / çabuk toparlanma","te":"Noun","tt":"İsim","de":"The capacity to recover quickly from difficulties; toughness","dt":"Zorluklar karşısında yılmama ve çabuk toparlanma yetisi; veya bir maddenin esnekliği","e1":"The resilience of the local economy.","e1t":"Yerel ekonominin (şoklara karşı) direnci.","e2":"Emotional resilience.","e2t":"Duygusal dayanıklılık."},{"w":"resound","tr":"yankılanmak / çınlamak / şan salmak","te":"Verb","tt":"Fiil","de":"(Of a place) be filled with or echo with a distant sound","dt":"Bir yerin sesle dolması veya bir haberin her yerde duyulması","e1":"The hall resounded with applause.","e1t":"Salon alkışlarla yankılandı.","e2":"A resounding success.","e2t":"Her yerde konuşulan (muazzam) bir başarı."},{"w":"resourceful","tr":"becerikli / çözüm üreten / işini bilen","te":"Adjective","tt":"Sıfat","de":"Having the ability to find quick and clever ways to overcome difficulties","dt":"Zor durumlarda elindeki imkanları en iyi şekilde kullanan ve çözüm bulan","e1":"A resourceful manager.","e1t":"Becerikli (iş bitirici) bir müdür.","e2":"He is quite resourceful.","e2t":"O oldukça beceriklidir (yol yordam bilir)."},{"w":"responsiveness","tr":"duyarlılık / tepki verme hızı","te":"Noun","tt":"İsim","de":"The quality of reacting quickly and positively","dt":"Bir uyarıya veya isteğe çabuk ve olumlu tepki verme özelliği","e1":"The responsiveness of the steering.","e1t":"Direksiyonun tepki hızı (duyarlılığı).","e2":"Business responsiveness to customer needs.","e2t":"İşletmenin müşteri ihtiyaçlarına duyarlılığı."},{"w":"resurge","tr":"yeniden canlanmak / tekrar ortaya çıkmak","te":"Verb","tt":"Fiil","de":"Increase or revive after a period of little activity, popularity, or occurrence","dt":"Bir durgunluk döneminden sonra tekrar güç kazanmak","e1":"The disease resurged in the winter.","e1t":"Hastalık kışın tekrar baş gösterdi (hortladı).","e2":"Resurgence (noun).","e2t":"Yeniden canlanma."},{"w":"resurrection","tr":"diriliş / yeniden canlanma","te":"Noun","tt":"İsim","de":"The action or fact of resurrecting or being resurrected","dt":"Ölümden sonra dirilme; veya (mecazi) unutulmuş bir şeyin tekrar hayata dönmesi","e1":"The Resurrection of Jesus.","e1t":"Hz. İsa'nın dirilişi.","e2":"The resurrection of his career.","e2t":"Kariyerinin yeniden canlanması."},{"w":"retraction","tr":"geri çekme / (sözünü) geri alma","te":"Noun","tt":"İsim","de":"The action of drawing something back or back in; or a withdrawal of a statement","dt":"Bir nesnenin geri çekilmesi; veya bir ifadenin (yanlış olduğu için) geri alınması","e1":"To issue a formal retraction.","e1t":"Resmi bir yalanlama (sözünü geri alma) yayınlamak.","e2":"Retract (verb).","e2t":"Geri çekmek."},{"w":"revitalize","tr":"yeniden canlandırmak / hayat vermek","te":"Verb","tt":"Fiil","de":"Imbue (something) with new life and vitality","dt":"Bir şeye (bölge/ekonomi/vücut) yeni bir enerji ve canlılık katmak","e1":"To revitalize the inner city.","e1t":"Şehir merkezini canlandırmak.","e2":"Revitalization (noun).","e2t":"Canlanma."},{"w":"revulsion","tr":"iğrenme / nefret / ani duygu değişimi","te":"Noun","tt":"İsim","de":"A sense of disgust and loathing","dt":"Bir şeye karşı duyulan ani ve şiddetli tiksinti","e1":"A feeling of revulsion.","e1t":"Bir iğrenme (nefret) hissi.","e2":"She looked at him with revulsion.","e2t":"Ona nefretle (iğrenerek) baktı."},{"w":"rhapsodize","tr":"ballandıra ballandıra anlatmak / coşkuyla övmek","te":"Verb","tt":"Fiil","de":"Speak or write about someone or something with great enthusiasm and delight","dt":"Bir şey hakkında büyük bir heyecan ve hayranlıkla konuşmak","e1":"He rhapsodized about the beauty of the island.","e1t":"Adanın güzelliğini ballandıra ballandıra anlattı.","e2":"To rhapsodize over a new movie.","e2t":"Yeni bir filmi yere göğe sığdıramamak."},{"w":"rhapsody","tr":"rapsodi / coşku dolu söz veya müzik","te":"Noun","tt":"İsim","de":"An effusively enthusiastic or ecstatic expression of feeling; or a free","dt":"form musical composition","e1":"Coşku dolu ifade; veya serbest yapılı müzik eseri","e1t":"Bohemian Rhapsody.","e2":"Bohem Rapsodisi.","e2t":"A rhapsody of praise."},{"w":"rhetorical","tr":"söz sanatı ile ilgili / hitabetle ilgili / cevap beklenmeyen","te":"Adjective","tt":"Sıfat","de":"Relating to or concerned with the art of rhetoric; or (of a question) asked in order to produce an effect, for other than information","dt":"Hitabet sanatı ile ilgili; veya (soru için) cevap beklemeyen, sadece vurgu amaçlı sorulan","e1":"A rhetorical question.","e1t":"Sözde (cevap beklenmeyen) soru.","e2":"Rhetorical devices.","e2t":"Söz sanatları (teşbih, mecaz vb.)."},{"w":"rider","tr":"madde / ek madde / binici","te":"Noun","tt":"İsim","de":"A person who is riding or who can ride something; or an additional clause or condition added to a document","dt":"Binici; veya bir yasa ya da sözleşmeye eklenen ilave madde","e1":"A motorcycle rider.","e1t":"Motosiklet sürücüsü.","e2":"To attach a rider to a bill.","e2t":"Bir kanun tasarısına ek madde eklemek."},{"w":"roil","tr":"bulandırmak / (sıvıyı) karıştırmak / sinirlendirmek","te":"Verb","tt":"Fiil","de":"Make (a liquid) turbid or muddy by disturbing the sediment; or to make someone annoyed","dt":"Suyu karıştırıp bulandırmak; veya (mecazi) birini öfkelendirmek","e1":"The storm roiled the sea.","e1t":"Fırtına denizi altüst etti (bulandırdı).","e2":"The controversy roiled the community.","e2t":"Tartışma toplumu ayağa kaldırdı (karıştırdı)."},{"w":"roister","tr":"gürültülü eğlenmek / kabadayılık taslamak","te":"Verb","tt":"Fiil","de":"Enjoy oneself or celebrate in a noisy or boisterous way","dt":"Gürültülü, neşeli ve biraz da taşkın bir şekilde eğlenmek","e1":"Roistering students.","e1t":"Gürültülü bir şekilde eğlenen öğrenciler.","e2":"Roisterer (noun).","e2t":"Alemi seven gürültücü tip."},{"w":"romp","tr":"neşeyle oynaşmak / (yarışı) kolayca kazanmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"(Especially of a child or animal) play about roughly and energetically","dt":"Çocuklar veya hayvanlar gibi hoplayıp zıplayarak oynamak; veya (mecazi) açık farkla kazanmak","e1":"The puppies were romping in the garden.","e1t":"Köpek yavruları bahçede neşeyle oynaşıyorlardı.","e2":"He romped to victory in the final.","e2t":"Finalde çok rahat (fark atarak) kazandı."},{"w":"rotunda","tr":"rotunda / yuvarlak bina (veya oda)","te":"Noun","tt":"İsim","de":"A round building or room, especially one with a dome","dt":"Genellikle kubbeli olan yuvarlak yapı veya büyük yuvarlak oda","e1":"The Capitol rotunda.","e1t":"Capitol binasının büyük yuvarlak salonu.","e2":"","e2t":""},{"w":"rotundity","tr":"yuvarlaklık / tombişlik / (ses) tokluk","te":"Noun","tt":"İsim","de":"The condition or quality of being round or plump; or the sonorousness of a voice","dt":"Yuvarlak olma hali; veya vücudun dolgunluğu; veya sesin gürlüğü/tokluğu","e1":"The rotundity of his belly.","e1t":"Karnının yuvarlaklığı (tombişliği).","e2":"Rotund (adjective).","e2t":"Yuvarlak / Tombul."},{"w":"rubric","tr":"başlık / yönerge / değerlendirme kriteri","te":"Noun","tt":"İsim","de":"A heading on a document; or a set of instructions or rules","dt":"Belge başlığı; veya (eğitimde) bir işin nasıl puanlanacağını gösteren kriterler tablosu","e1":"Under the rubric of...","e1t":"... başlığı (kategorisi) altında.","e2":"A scoring rubric for the essay.","e2t":"Kompozisyon için puanlama kriterleri (rubrik)."},{"w":"ruddy","tr":"kırmızımsı / sağlıklı ve al (yüz)","te":"Adjective","tt":"Sıfat","de":"(Of a person's face) having a healthy red color","dt":"(Yüz için) canlı, sağlıklı ve pembe/kırmızı renkli","e1":"Ruddy cheeks.","e1t":"Al al (kırmızı) yanaklar.","e2":"A ruddy complexion.","e2t":"Sağlıklı, taze bir cilt."},{"w":"runic","tr":"runik / gizemli (yazı)","te":"Adjective","tt":"Sıfat","de":"Relating to or written in runes; or mysterious; magical","dt":"Eski Germen/İskandinav yazılarına (run) ait; veya gizemli","e1":"Runic inscriptions.","e1t":"Runik yazıtlar.","e2":"Runic symbols.","e2t":"Gizemli semboller."},{"w":"sabbatical","tr":"akademik izin / seyyahat izni","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A period of paid leave granted to a university teacher or other worker for study or travel, traditionally one year for every seven years worked","dt":"Uzun süreli çalışma sonrası verilen dinlenme veya araştırma izni","e1":"To take a sabbatical year.","e1t":"Bir yıl akademik izin kullanmak.","e2":"He is on sabbatical.","e2t":"İzinli (araştırma için)."},{"w":"sacerdotal","tr":"ruhban sınıfına ait / rahiplerle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to priests or the priesthood; priestly","dt":"Din adamlarıyla veya rahiplik makamıyla ilgili","e1":"Sacerdotal duties.","e1t":"Rahip görevleri.","e2":"Sacerdotalism (noun).","e2t":"Ruhbanlık sistemi."},{"w":"sacrament","tr":"kutsal tören / sakrament","te":"Noun","tt":"İsim","de":"A religious ceremony or act of the Christian Church which is regarded as an outward and visible sign of inward and spiritual divine grace","dt":"Hristiyanlıkta Tanrı'nın lütfunu temsil eden kutsal törenler (vaftiz vb.)","e1":"The sacrament of baptism.","e1t":"Vaftiz sakramenti.","e2":"Sacramental (adjective).","e2t":"Kutsal törenle ilgili."},{"w":"saline","tr":"tuzlu / tuz içeren / serum","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Containing or impregnated with salt","dt":"Tuz içeren; veya tıbbi tuzlu su çözeltisi","e1":"Saline solution.","e1t":"Serum fizyolojik (tuzlu su çözeltisi).","e2":"Saline deposits.","e2t":"Tuz yatakları."},{"w":"sallow","tr":"soluk benizli / sarımtırak (yüz)","te":"Adjective","tt":"Sıfat","de":"(Of a person's face or complexion) of an unhealthy yellow or pale brown color","dt":"(Yüz için) sağlıksız görünen, sarımtırak ve solgun","e1":"A sallow complexion.","e1t":"Soluk (hastalıklı) bir ten rengi.","e2":"He looked thin and sallow.","e2t":"Zayıf ve soluk benizli görünüyordu."},{"w":"salutation","tr":"selamlama / selam","te":"Noun","tt":"İsim","de":"A gesture or utterance made as a greeting or acknowledgment of another's arrival or departure","dt":"Birini selamlama eylemi veya sözü","e1":"A formal salutation.","e1t":"Resmi bir selamlama.","e2":"The salutation of a letter (e.g., Dear Sir).","e2t":"Mektup hitabı."},{"w":"sanctity","tr":"kutsallık / dokunulmazlık","te":"Noun","tt":"İsim","de":"The state or quality of being holy, sacred, or saintly","dt":"Bir şeyin kutsal veya dokunulmaz olma durumu","e1":"The sanctity of life.","e1t":"Hayatın kutsallığı.","e2":"The sanctity of marriage.","e2t":"Evliliğin kutsallığı."},{"w":"sap","tr":"suyunu çekmek / tüketmek / bitki özsuyu / enayi","te":"Verb/Noun","tt":"Fiil/İsim","de":"Gradually weaken or destroy (a person's strength or confidence); or the fluid in plants","dt":"Birinin gücünü veya enerjini yavaş yavaş bitirmek; veya bitki özsuyu","e1":"The heat sapped my energy.","e1t":"Sıcaklık enerjimi tüketti.","e2":"To sap someone's confidence.","e2t":"Birinin özgüvenini kırmak."},{"w":"sarcophagus","tr":"lahit / taş tabut","te":"Noun","tt":"İsim","de":"A stone coffin, typically adorned with a sculpture or inscription and associated with the ancient civilizations","dt":"Genellikle süslemeli ve yazıtlı olan antik taş tabut","e1":"An Egyptian sarcophagus.","e1t":"Bir Mısır lahdi.","e2":"(Plural: Sarcophagi).","e2t":""},{"w":"sartorial","tr":"giyimle ilgili / terzilikle ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to tailoring, clothes, or style of dress","dt":"Terzilik veya kıyafet tarzı ile ilgili","e1":"Sartorial elegance.","e1t":"Giyim kuşam şıklığı.","e2":"To make a sartorial mistake.","e2t":"Giyim konusunda bir hata yapmak."},{"w":"sate","tr":"doyurmak / bıktırmak","te":"Verb","tt":"Fiil","de":"Satisfy (a desire or an appetite) to the full","dt":"Bir arzuyu veya iştahı tamamen tatmin etmek (doyurmak)","e1":"To sate one's curiosity.","e1t":"Merakını gidermek (doyurmak).","e2":"Sated with food.","e2t":"Yemeğe doymuş."},{"w":"satirize","tr":"hicvetmek / alay ederek eleştirmek","te":"Verb","tt":"Fiil","de":"Deride and criticize by means of satire","dt":"Bir durumu veya kişiyi hiciv yoluyla eleştirmek","e1":"The movie satirizes the fashion industry.","e1t":"Film moda dünyasını hicvediyor.","e2":"To satirize a politician.","e2t":"Bir siyasetçiyi yermek (onunla dalga geçmek)."},{"w":"saturnine","tr":"asık suratlı / somurtkan / melankolik","te":"Adjective","tt":"Sıfat","de":"(Of a person or their manner) slow and gloomy","dt":"(Kişi için) ağırkanlı, ciddi ve karamsar","e1":"A saturnine expression.","e1t":"Somurtkan bir ifade.","e2":"His saturnine features.","e2t":"Onun ciddi ve asık yüz hatları. (Not: İsmini Satürn gezegeninin soğuk ve ağır etkisinden"},{"w":"saunter","tr":"ağır ağır gezinmek / yaylana yaylana yürümek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Walk in a slow, relaxed manner, without hurry or effort","dt":"Telaşsız ve keyifli bir şekilde yavaşça yürümek","e1":"He sauntered down the street.","e1t":"Sokakta ağır ağır gezindi.","e2":"A pleasant saunter.","e2t":"Keyifli bir gezinti."},{"w":"savant","tr":"bilgin / dahi (belli bir alanda)","te":"Noun","tt":"İsim","de":"A learned person, especially a distinguished scientist","dt":"Özellikle bilim alanında çok derin bilgi sahibi olan kişi; veya üstün zekalı","e1":"An eminent savant.","e1t":"Seçkin bir bilgin.","e2":"Idiot savant (belli bir alanda dahi olan zihinsel engelli kişi).","e2t":""},{"w":"savor / savour","tr":"tadını çıkarmak / lezzet / koku","te":"Verb/Noun","tt":"Fiil/İsim","de":"Enjoy or appreciate (something pleasant) completely, especially by dwelling on it; or a characteristic taste","dt":"Bir şeyin (yemek/an) tadına vararak keyfini sürmek; veya kendine has lezzet","e1":"To savor every moment of the holiday.","e1t":"Tatilin her anının tadını çıkarmak.","e2":"To savor a glass of wine.","e2t":"Bir kadeh şarabın lezzetine varmak."},{"w":"savory","tr":"lezzetli / iştah açıcı / tuzlu","te":"baharatlı","tt":"Adjective","de":"Sıfat","dt":"(Of food) belonging to the category that is salty or spicy rather than sweet","e1":"(Yemek için) tatlı olmayan, tuzlu veya baharatlı (iştah açıcı)","e1t":"A savory snack.","e2":"Tuzlu bir atıştırmalık.","e2t":"The savory smell of baking bread."},{"w":"scabbard","tr":"kın (kılıç/bıçak)","te":"Noun","tt":"İsim","de":"A sheath for the blade of a sword or dagger, typically made of leather or metal","dt":"Kılıç veya kama kılıfı","e1":"To draw a sword from its scabbard.","e1t":"Kılıcı kınından çekmek.","e2":"To return the blade to the scabbard.","e2t":"Kılıcı kınına sokmak."},{"w":"scad","tr":"çok büyük miktar / yığınla","te":"Noun","tt":"İsim (Plural)","de":"A large number or quantity","dt":"Çok fazla sayıda olan şey","e1":"Scads of money.","e1t":"Yığınla para.","e2":"Scads of people.","e2t":"Bir dünya (çok sayıda) insan."},{"w":"scaffold","tr":"iskele / idam sehpası","te":"Noun/Verb","tt":"İsim/Fiil","de":"A temporary structure on the outside of a building, made of wooden planks and metal poles; or a platform for execution","dt":"İnşaat iskelesi; veya asılarak idam edilen platform","e1":"To work on a scaffold.","e1t":"İskelede çalışmak.","e2":"To lead someone to the scaffold.","e2t":"Birini idam sehpasına götürmek."},{"w":"scamp","tr":"haylaz / yaramaz (çocuk) / yarım yamalak yapmak","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person, especially a child, who is mischievous in a likable or amusing way; or to do work carelessly","dt":"Sevimli yaramaz (haylaz); veya (fiil) bir işi baştan savma yapmak","e1":"You little scamp!","e1t":"Seni gidi haylaz seni!","e2":"To scamp one's work.","e2t":"İşi yarım yamalak (üstünkörü) yapmak."},{"w":"scapegoat","tr":"günah keçisi","te":"Noun/Verb","tt":"İsim/Fiil","de":"A person who is blamed for the wrongdoings, mistakes, or faults of others","dt":"Başkalarının hatası yüzünden suçlanan kişi","e1":"To make someone a scapegoat.","e1t":"Birini günah keçisi ilan etmek.","e2":"He was used as a scapegoat for the company's failure.","e2t":"Şirketin başarısızlığı için günah keçisi olarak kullanıldı."},{"w":"scenario","tr":"senaryo / olası durum","te":"Noun","tt":"İsim","de":"A written outline of a movie, novel, or stage work; or a postulated sequence of events","dt":"Film veya oyun taslağı; veya gelecekte olması muhtemel olaylar dizisi","e1":"To write a movie scenario.","e1t":"Film senaryosu yazmak.","e2":"The worst","e2t":"case scenario."},{"w":"schematic","tr":"şematik / taslak halinde","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"(Of a diagram or other representation) symbolic and simplified; or a diagram","dt":"Ayrıntıya girmeden sadece ana hatları gösteren; veya (isim) şema","e1":"A schematic diagram of the engine.","e1t":"Motorun şematik diyagramı.","e2":"To follow a schematic plan.","e2t":"Şematik bir planı takip etmek."},{"w":"scruple","tr":"vicdan azabı / tereddüt / şüphe","te":"Noun/Verb","tt":"İsim/Fiil","de":"A feeling of doubt or hesitation with regard to the morality or propriety of a course of action","dt":"Bir işin ahlaki olup olmadığı konusunda duyulan kuşku (vicdan yapma)","e1":"He had no scruples about lying.","e1t":"Yalan söyleme konusunda hiç vicdanı sızlamadı.","e2":"To scruple to do something (bir şeyi yaparken tereddüt etmek).","e2t":""},{"w":"scrutinize","tr":"didik didik etmek / çok dikkatli incelemek","te":"Verb","tt":"Fiil","de":"Examine or inspect closely and thoroughly","dt":"Bir şeyi en ince ayrıntısına kadar dikkatle gözden geçirmek","e1":"To scrutinize the documents.","e1t":"Belgeleri titizlikle incelemek.","e2":"Every detail was scrutinized by the experts.","e2t":"Her detay uzmanlar tarafından didik didik edildi."},{"w":"scurrilous","tr":"aşağılayıcı / küfürlü / edepsiz","te":"Adjective","tt":"Sıfat","de":"Making or spreading scandalous claims about someone with the intention of damaging their reputation","dt":"Birinin itibarını sarsmak için söylenen kaba ve hakaret dolu","e1":"Scurrilous rumors.","e1t":"Çirkin (aşağılayıcı) söylentiler.","e2":"Scurrilous attacks in the press.","e2t":"Basındaki kaba ve hakaretamiz saldırılar."},{"w":"sebaceous","tr":"yağlı / yağ bezlerine ait","te":"Adjective","tt":"Sıfat","de":"Relating to oil or fat; or denoting glands which secrete oil","dt":"Yağ salgılayan bezlerle ilgili; yağlı","e1":"Sebaceous glands in the skin.","e1t":"Ciltteki yağ bezleri.","e2":"Sebaceous cyst.","e2t":"Yağ kisti."},{"w":"secede","tr":"ayrılmak / bağımsızlığını ilan etmek","te":"Verb","tt":"Fiil","de":"Withdraw formally from membership of a federal union, an alliance, or a political or religious organization","dt":"Bir birlikten veya devletten resmi olarak ayrılmak","e1":"The southern states attempted to secede from the Union.","e1t":"Güney eyaletleri birlikten ayrılmaya çalıştı.","e2":"Secession (noun).","e2t":"Ayrılma."},{"w":"seclusion","tr":"inziva / dış dünyadan kopma","te":"Noun","tt":"İsim","de":"The state of being private and away from other people","dt":"Diğer insanlardan uzak, tek başına olma hali","e1":"He lives in total seclusion.","e1t":"Tamamen inziva içinde yaşıyor.","e2":"The seclusion of the monastery.","e2t":"Manastırın dış dünyadan kopukluğu."},{"w":"seduce","tr":"ayartmak / yoldan çıkarmak / baştan çıkarmak","te":"Verb","tt":"Fiil","de":"Entice (someone) to do something, typically a personal or unwise thing; or to attract","dt":"Birini (genellikle yanlış bir şeye) ikna edip kandırmak veya baştan çıkarmak","e1":"To seduce someone with promises of wealth.","e1t":"Birini zenginlik vaatleriyle kandırmak.","e2":"Seductive (adjective).","e2t":"Baştan çıkarıcı."},{"w":"seedy","tr":"bakımsız / şüpheli / perişan / çekirdekli","te":"Adjective","tt":"Sıfat","de":"Sordid and disreputable; or run","dt":"down; shabby","e1":"Görünüşü kötü, tekinsiz ve bakımsız olan","e1t":"A seedy hotel.","e2":"Köhne ve tekinsiz bir otel.","e2t":"He looked a bit seedy after the party."},{"w":"seemly","tr":"uygun / yakışık alan / terbiyeli","te":"Adjective","tt":"Sıfat","de":"Conforming to accepted standards of moral or social behavior; proper","dt":"Toplum kurallarına ve görgüye uygun olan","e1":"It was not felt seemly to celebrate during a time of mourning.","e1t":"Yas zamanında kutlama yapmak uygun görülmedi.","e2":"Seemly behavior.","e2t":"Yakışık alan davranış. (Not: Unseemly"},{"w":"seminary","tr":"papaz okulu / ilahiyat okulu","te":"Noun","tt":"İsim","de":"A college that prepares students to be priests, ministers, or rabbis","dt":"Din adamı yetiştiren yüksekokul","e1":"He entered the seminary at eighteen.","e1t":"On sekiz yaşında papaz okuluna girdi.","e2":"","e2t":""},{"w":"senile","tr":"bunamış / yaşlılık kaynaklı zayıflık","te":"Adjective","tt":"Sıfat","de":"(Of a person) having or showing the weaknesses or diseases of old age, especially a loss of mental faculties","dt":"Yaşlılıktan dolayı zihni melekelerini yitirmiş","e1":"Senile dementia.","e1t":"Yaşlılık bunaması.","e2":"He is becoming senile.","e2t":"Bunamaya başlıyor."},{"w":"sensuous","tr":"duyulara hitap eden / estetik","te":"Adjective","tt":"Sıfat","de":"Relating to or affecting the senses rather than the intellect","dt":"Estetik olarak duyuları etkileyen (hoş)","e1":"Sensuous music.","e1t":"Duyulara hitap eden müzik.","e2":"The sensuous feel of silk.","e2t":"İpeğin ten üzerindeki hoş hissi."},{"w":"sententious","tr":"özlü konuşan / bilgiçlik taslayan / ahlakçı","te":"Adjective","tt":"Sıfat","de":"Given to moralizing in a pompous or affected manner","dt":"Sürekli ahlaki dersler veren ve bilgiçlik taslayan","e1":"A sententious speech.","e1t":"Bilgiççe ve ahlakçı bir konuşma.","e2":"He is a sententious old man.","e2t":"Sürekli nasihat veren bilgiç bir ihtiyardır."},{"w":"septic","tr":"zehirli / enfeksiyonlu / septik","te":"Adjective","tt":"Sıfat","de":"(Chiefly of a wound or part of the body) infected with bacteria","dt":"Bakteriler nedeniyle iltihaplanmış veya zehirlenmiş","e1":"The wound has gone septic.","e1t":"Yara mikrop kapmış (iltihaplanmış).","e2":"Septic tank.","e2t":"Foseptik tankı."},{"w":"sequester","tr":"el koymak / tecrit etmek / ayırmak","te":"Verb","tt":"Fiil","de":"Isolate or hide away (someone or something); or to take legal possession of assets","dt":"Birini veya bir şeyi dış dünyadan ayırmak (tecrit etmek); veya mallara el koymak","e1":"The jury was sequestered during the trial.","e1t":"Jüri, dava süresince dış dünyadan tecrit edildi.","e2":"To sequester carbon (karbon tutmak/hapsetmek).","e2t":""},{"w":"seraphic","tr":"melek gibi / saf ve huzurlu","te":"Adjective","tt":"Sıfat","de":"Characteristic of or resembling a seraph or seraphim; angelic","dt":"En üst rütbeli melek gibi (seraf); çok huzurlu ve saf","e1":"A seraphic smile.","e1t":"Melekvari (saf ve huzurlu) bir gülümseme.","e2":"Seraph (noun).","e2t":"Seraf (melek türü)."},{"w":"serpentine","tr":"yılan gibi / kıvrımlı / sinsi","te":"Adjective","tt":"Sıfat","de":"Of or like a serpent or snake; winding and twisting","dt":"Yılan gibi kıvrılan (yol vb.); veya (mecazi) sinsi ve karmaşık","e1":"A serpentine road through the mountains.","e1t":"Dağların arasından kıvrılarak giden yol.","e2":"Serpentine logic.","e2t":"Dolambaçlı ve sinsi bir mantık."},{"w":"serrated","tr":"testere dişli / tırtıklı","te":"Adjective","tt":"Sıfat","de":"Having or denoting a jagged edge; saw","dt":"edged","e1":"Kenarı dişli veya tırtıklı olan","e1t":"A serrated knife.","e2":"Testere dişli bıçak.","e2t":"Serrated leaves."},{"w":"servitude","tr":"esaret / kölelik / zorunlu hizmet","te":"Noun","tt":"İsim","de":"The state of being a slave or completely subject to someone more powerful","dt":"Başkasının boyunduruğu altında olma durumu; kölelik","e1":"Penal servitude (kürek mahkumiyeti/ağır hapis).","e1t":"To live in servitude.","e2":"Esaret altında yaşamak.","e2t":""},{"w":"sham","tr":"sahte / düzmece / numara","te":"Noun/Adjective/Verb","tt":"A thing that is not what it is purported to be; a pretense","de":"Gerçek olmayan, aldatmaca; veya numara yapmak","dt":"The wedding was a sham.","e1":"Düğün bir düzmeceydi (sahteydi).","e1t":"A sham doctor.","e2":"Sahte doktor.","e2t":""},{"w":"shambles","tr":"kargaşa / darmadağın yer / mezbaha","te":"Noun","tt":"İsim","de":"A state of total disorder; or a slaughterhouse","dt":"Her şeyin birbirine girdiği darmadağın yer (mahşer yeri)","e1":"The meeting was a total shambles.","e1t":"Toplantı tam bir fiyaskoydu (kargaşaydı).","e2":"After the party, the house was a shambles.","e2t":"Partiden sonra ev savaş alanına dönmüştü."},{"w":"shard","tr":"cam veya çömlek kırığı / parça","te":"Noun","tt":"İsim","de":"A piece of broken ceramic, metal, glass, or rock, typically having sharp edges","dt":"Keskin kenarlı kap","e1":"kacak veya cam parçası","e1t":"Shards of glass on the floor.","e2":"Yerdeki cam kırıkları.","e2t":"Pottery shards found in the excavation."},{"w":"sheathe","tr":"kınına sokmak / kaplamak","te":"Verb","tt":"Fiil","de":"Put (a weapon such as a knife or sword) into a sheath; or to cover in a protective layer","dt":"Bıçağı veya kılıcı kılıfına sokmak; veya üzerini bir tabaka ile örtmek","e1":"To sheathe a sword.","e1t":"Kılıcı kınına sokmak.","e2":"Cables sheathed in plastic.","e2t":"Plastikle kaplanmış kablolar."},{"w":"sherbet","tr":"şerbet / (İngiltere'de) meyveli toz şeker","te":"Noun","tt":"İsim","de":"A cooling drink of sweetened fruit juice and water; or a flavored sparkling powder eaten as a sweet","dt":"Tatlı meyve suyu karışımı; veya ağızda patlayan şeker tozu","e1":"To drink traditional Turkish sherbet.","e1t":"Geleneksel Türk şerbeti içmek.","e2":"Lemon sherbet.","e2t":"Limonlu şerbet."},{"w":"shoddy","tr":"kalitesiz / uyduruk / kötü yapılmış","te":"Adjective","tt":"Sıfat","de":"Badly made or done","dt":"Çok kalitesiz malzemeden, özen gösterilmeden yapılan","e1":"Shoddy workmanship.","e1t":"Baştan savma (kötü) işçilik.","e2":"Shoddy goods.","e2t":"Adi (kalitesiz) mallar."},{"w":"shrift","tr":"günah çıkarma / itiraf","te":"Noun","tt":"İsim","de":"Confession, especially to a priest","dt":"(Eski kullanım) Papaza yapılan günah çıkarma","e1":"To give short shrift to something (bir meseleyi başından hemen savmak / pek ilgilenmemek).","e1t":"","e2":"","e2t":""},{"w":"shrivel","tr":"büzülmek / kurumak / kırışmak","te":"Verb","tt":"Fiil","de":"Wrinkle and contract or cause to wrinkle and contract, especially due to loss of moisture","dt":"(Bitki/deri vb.) susuzluktan veya yaşlılıktan büzülüp kurumak","e1":"The leaves shriveled in the sun.","e1t":"Yapraklar güneşte kavrulup büzüldü.","e2":"To shrivel up (kuruyup gitmek).","e2t":""},{"w":"shunt","tr":"başka yöne çevirmek / (tren) hat değiştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Push or pull (a train or part of a train) from the main line to a siding; or to redirect","dt":"Bir şeyi (veya birini) ana yoldan yan yola veya daha önemsiz bir yere aktarmak","e1":"The passengers were shunted onto a bus.","e1t":"Yolcular bir otobüse aktarıldı.","e2":"To shunt a problem aside.","e2t":"Bir problemi bir kenara itmek."},{"w":"simulated","tr":"sahte / yapay / taklit edilmiş","te":"Adjective","tt":"Sıfat","de":"Manufactured in imitation of some other material; or pretended; feigned","dt":"Gerçek olmayan, bir şeyi taklit etmek için üretilen","e1":"Simulated fur.","e1t":"Yapay kürk.","e2":"Simulated conditions.","e2t":"Simüle edilmiş (yapay) koşullar."},{"w":"skinflint","tr":"pinti / aşırı cimri","te":"Noun","tt":"İsim","de":"A person who spends as little money as possible; a miser","dt":"Elinden beş kuruş çıkmayan, aşırı derecede cimri kişi","e1":"My boss is such a skinflint.","e1t":"Patronum tam bir pintidir.","e2":"","e2t":""},{"w":"skulk","tr":"gizlice dolaşmak / pusuya yatmak","te":"Verb","tt":"Fiil","de":"Keep out of sight, typically with a sinister or cowardly motive","dt":"Kötü bir niyetle veya korkudan dolayı gizlenerek dolaşmak","e1":"A man was skulking in the shadows.","e1t":"Gölgelerde gizlice dolaşan (pusuda bekleyen) bir adam vardı.","e2":"To skulk around the corner.","e2t":"Köşe başında gizlenmek."},{"w":"slapdash","tr":"baştan savma / üstünkörü / özensiz","te":"Adjective/Adverb","tt":"Sıfat/Zarf","de":"Done too hurriedly and carelessly","dt":"Aceleye getirilmiş ve dikkatsizce yapılmış","e1":"A slapdash piece of work.","e1t":"Üstünkörü yapılmış bir iş.","e2":"He did the repairs in a slapdash manner.","e2t":"Tamiratları baştan savma bir şekilde yaptı."},{"w":"sleight","tr":"el çabukluğu / beceri","te":"Noun","tt":"İsim","de":"The use of dexterity or cunning, especially so as to deceive","dt":"Özellikle kandırmak için kullanılan el becerisi","e1":"Sleight of hand (el çabukluğu/hokkabazlık).","e1t":"By a clever sleight of mind.","e2":"Zekice bir hileyle.","e2t":""},{"w":"sluggard","tr":"miskin / uyuşuk / çok tembel kimse","te":"Noun","tt":"İsim","de":"A lazy, sluggish person","dt":"Hiçbir şey yapmak istemeyen, ağır kanlı ve tembel kişi","e1":"Wake up, you sluggard!","e1t":"Uyan artık, seni miskin!","e2":"(Bkz: Sluggish).","e2t":""},{"w":"slur","tr":"leke sürmek / kelimeleri yuvarlamak / hakaret","te":"Verb/Noun","tt":"Fiil/İsim","de":"Speak distinctively so that the sounds run into one another; or an insinuation or allegation about someone that is likely to insult them","dt":"(İçkili veya hasta olduğu için) kelimeleri birbirine karıştırarak konuşmak; veya birinin itibarına kara çalmak","e1":"His speech was slurred.","e1t":"Konuşması peltekti (kelimeleri yuvarlıyordu).","e2":"A slur on his character.","e2t":"Karakterine sürülmüş bir leke (hakaret)."},{"w":"snicker","tr":"kıs kıs gülmek / bıyık altından gülmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Give a smothered or half","dt":"suppressed laugh; a snigger","e1":"(Genellikle başkasının düştüğü duruma) gizlice ve alaycı bir şekilde gülmek","e1t":"The students snickered behind the teacher's back.","e2":"Öğrenciler öğretmenin arkasından kıs kıs güldüler.","e2t":"(Bkz: Snigger)."},{"w":"sodden","tr":"sırılsıklam / (içkiden) aptallaşmış","te":"Adjective","tt":"Sıfat","de":"Saturated with liquid, especially water; soaked through","dt":"Suya tamamen doymuş, çok ıslanmış","e1":"Sodden clothes.","e1t":"Sırılsıklam kıyafetler.","e2":"The ground was sodden with rain.","e2t":"Toprak yağmurdan dolayı sırılsıklam olmuştu (çamura dönmüştü)."},{"w":"solarium","tr":"solaryum / güneşlenme odası","te":"Noun","tt":"İsim","de":"A room with glass walls and roof (sunroom); or an establishment for artificial tanning","dt":"Güneş ışığı girmesi için camla çevrili oda; veya yapay bronzlaşma merkezi","e1":"To relax in the solarium.","e1t":"Güneşlenme odasında dinlenmek.","e2":"A hospital solarium.","e2t":"Hastane güneşlenme salonu."},{"w":"solecism","tr":"dil bilgisi hatası / görgüsüzlük / yanlışlık","te":"Noun","tt":"İsim","de":"A grammatical mistake; or a breach of good manners","dt":"Konuşma veya yazıda yapılan dil bilgisi hatası; veya toplum içinde yapılan görgü hatası","e1":"To commit a solecism.","e1t":"Bir ifade hatası yapmak.","e2":"Social solecisms.","e2t":"Sosyal (görgü) hataları."},{"w":"solipsism","tr":"solipsizm / tekbencilik","te":"Noun","tt":"İsim","de":"The view or theory that the self is all that can be known to exist","dt":"Sadece kendi zihninin varlığından emin olunabileceğini savunan felsefi görüş","e1":"To fall into the trap of solipsism.","e1t":"Tekbencilik tuzağına düşmek.","e2":"Solipsistic (adjective).","e2t":"Sadece kendini düşünen / Tekbenci."},{"w":"somatic","tr":"bedensel / vücutla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to the body, especially as distinct from the mind","dt":"Zihinden ziyade fiziksel vücutla ilgili olan","e1":"Somatic cells.","e1t":"Vücut hücreleri.","e2":"Somatic symptoms.","e2t":"Bedensel belirtiler."},{"w":"spew","tr":"kusmak / fışkırtmak / saçmak","te":"Verb","tt":"Fiil","de":"Expel large quantities of (something) rapidly and forcibly","dt":"İçindeki sıvıyı veya gazı şiddetle dışarı vermek; veya (argo) kusmak","e1":"The volcano spewed ash into the air.","e1t":"Volkan havaya kül fışkırttı (saçtı).","e2":"Chimneys spewing out black smoke.","e2t":"Siyah duman kusan (çıkaran) bacalar."},{"w":"spindly","tr":"sıska / cılız / ince ve uzun","te":"Adjective","tt":"Sıfat","de":"(Of a person or limb) long or tall and thin","dt":"(Genellikle eşya veya vücut için) zayıf ve çelimsiz görünen","e1":"Spindly legs.","e1t":"Sıska bacaklar.","e2":"A spindly wooden chair.","e2t":"İnce ve dayanıksız görünen ahşap bir sandalye."},{"w":"stanch","tr":"(kan akışını) durdurmak / dindirmek","te":"Verb","tt":"Fiil","de":"Stop or restrict (a flow of blood or cash)","dt":"Kan kaybını veya para çıkışını durdurmak","e1":"To stanch the flow of blood.","e1t":"Kan akışını durdurmak.","e2":"Measures to stanch the losses.","e2t":"Kayıpları dindirmek (kesmek) için alınan önlemler."},{"w":"stereotyped","tr":"kalıplaşmış / basma kalıp / klişe","te":"Adjective","tt":"Sıfat","de":"Viewed or represented as a widespread but fixed and oversimplified image or idea of a particular type of person or thing","dt":"Önyargılara dayalı, değişmez ve basit bir kalıba sokulmuş","e1":"Stereotyped images of foreigners.","e1t":"Yabancılar hakkındaki basma kalıp (klişe) imgeler.","e2":"Stereotype (noun/verb).","e2t":"Kalıpyargı / Kalıba sokmak."},{"w":"stipple","tr":"noktalama yapmak / beneklemek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Engrave, paint, or draw by means of dots or small touches","dt":"Resim veya gravürde noktalar kullanarak desen oluşturmak","e1":"To stipple the background of a painting.","e1t":"Bir tablonun arka planını noktalarla işlemek.","e2":"A stippled effect.","e2t":"Noktalı (benekli) bir görünüm."},{"w":"stockade","tr":"kazıklı çit / parmaklık / askeri hapishane","te":"Noun/Verb","tt":"İsim/Fiil","de":"A barrier formed from upright wooden posts or stakes, especially as a defense","dt":"Savunma amacıyla dikilen yüksek kazıklardan oluşan duvar","e1":"The settlers built a stockade for protection.","e1t":"Yerleşimciler korunma için kazıklı bir çit inşa ettiler.","e2":"(Askeri terim) Disiplin hapsi yeri.","e2t":""},{"w":"stodgy","tr":"ağır ve hazmı zor / sıkıcı / hantal","te":"Adjective","tt":"Sıfat","de":"(Of food) heavy, filling, and high in carbohydrates; or dull and uninspired","dt":"(Yemek için) çok doyurucu ama mideye oturan; veya (mecazi) yaratıcılıktan uzak ve sıkıcı","e1":"A stodgy meal.","e1t":"Ağır (mideye oturan) bir yemek.","e2":"A stodgy old professor.","e2t":"Sıkıcı ve gelenekçi bir profesör."},{"w":"stoke","tr":"(ateşi) beslemek / körüklemek","te":"Verb","tt":"Fiil","de":"Add coal or other fuel to (a fire, furnace, or boiler); or to encourage a strong emotion","dt":"Ocağa yakıt atarak ateşi canlı tutmak; veya (mecazi) bir duyguyu (öfke/merak vb.) artırmak","e1":"To stoke the furnace.","e1t":"Ocağı (kazanı) beslemek.","e2":"His comments only stoked her anger.","e2t":"Onun yorumları kadının öfkesini daha da körükledi."},{"w":"stymie","tr":"engel olmak / tıkamak / eli kolu bağlamak","te":"Verb","tt":"Fiil","de":"Prevent or hinder the progress of","dt":"Bir işin ilerlemesine engel olmak veya onu çıkmaza sokmak","e1":"The project was stymied by a lack of funds.","e1t":"Proje, ödenek yokluğu nedeniyle tıkandı (engellendi).","e2":"To stymie someone's efforts.","e2t":"Birinin çabalarını boşa çıkarmak."},{"w":"subaqueous","tr":"su altı / suyun altındaki","te":"Adjective","tt":"Sıfat","de":"Existing, occurring, or used under the surface of water","dt":"Suyun yüzeyinin altında bulunan veya gerçekleşen","e1":"Subaqueous plants.","e1t":"Su altı bitkileri.","e2":"Subaqueous construction.","e2t":"Su altı inşaatı."},{"w":"sublime","tr":"muazzam / yüce / eşsiz / katıdan gaza geçmek","te":"Adjective/Verb","tt":"Of such excellence, grandeur, or beauty as to inspire great admiration","de":"Hayranlık uyandıracak kadar muhteşem ve yüce; veya (kimyada) süblimleşmek","dt":"The sublime beauty of the mountains.","e1":"Dağların yüce (muazzam) güzelliği.","e1t":"To go from the ridiculous to the sublime.","e2":"Gülünç olandan muazzam olana geçmek.","e2t":""},{"w":"supernal","tr":"ilahi / göksel / yüce","te":"Adjective","tt":"Sıfat","de":"Relating to the sky or the heavens; celestial","dt":"Gökyüzüne veya cennete ait; olağanüstü yüce","e1":"Supernal beauty.","e1t":"İlahi (göksel) güzellik.","e2":"Supernal powers.","e2t":"Doğaüstü (yüce) güçler."},{"w":"supernumerary","tr":"kadro dışı / fazladan / figüran","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Present in excess of the normal or requisite number; extra","dt":"Gereken sayıdan fazla olan; veya (tiyatroda) dilsiz figüran","e1":"A supernumerary tooth.","e1t":"Fazladan çıkmış diş.","e2":"To work as a supernumerary.","e2t":"Figüran olarak çalışmak."},{"w":"suppliant","tr":"yalvaran / rica eden / müstedi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person making a humble or earnest plea to someone in power or authority","dt":"Bir otoriteye boyun eğerek ricada bulunan veya yalvaran kişi","e1":"To fall on one's knees as a suppliant.","e1t":"Yalvaran bir kişi olarak diz çökmek.","e2":"A suppliant look.","e2t":"Rica eden (mahzun) bir bakış."},{"w":"supposititious","tr":"sahte / uydurma / varsayılan","te":"Adjective","tt":"Sıfat","de":"Substituted for the real thing; spurious; or hypothetical","dt":"Gerçek olanın yerine konmuş (sahte); veya varsayımsal","e1":"A supposititious child.","e1t":"(Miras için) başkasının yerine konmuş sahte çocuk.","e2":"Supposititious evidence.","e2t":"Uydurma kanıt."},{"w":"sweltering","tr":"bunaltıcı sıcak / terleten","te":"Adjective","tt":"Sıfat","de":"Unpleasantly hot","dt":"Çok yüksek ve rahatsız edici sıcaklık","e1":"Sweltering heat.","e1t":"Kavurucu (bunaltıcı) sıcaklık.","e2":"A sweltering summer day.","e2t":"Terleten bir yaz günü."},{"w":"swerve","tr":"sapmak / aniden yön değiştirmek","te":"Verb/Noun","tt":"Fiil/İsim","de":"Change or cause to change direction abruptly","dt":"(Genellikle çarpmamak için) aniden direksiyon kırmak veya yoldan sapmak","e1":"The car swerved to avoid the dog.","e1t":"Araba köpeğe çarpmamak için aniden saptı.","e2":"To swerve from one's principles.","e2t":"Prensiplerinden sapmak."},{"w":"swill","tr":"iştahla içmek / çalkalamak / yiyecek artığı","te":"Verb/Noun","tt":"Fiil/İsim","de":"Drink greedily or large quantities of; or wash out with large amounts of water","dt":"Büyük yudumlarla iştahla içmek; veya suyla çalkalamak; veya domuz yemi","e1":"To swill beer.","e1t":"Birayı mideye indirmek (içmek).","e2":"To swill out the bucket.","e2t":"Kovayı suyla çalkalayıp temizlemek."},{"w":"swindler","tr":"dolandırıcı / sahtekar","te":"Noun","tt":"İsim","de":"A person who uses deception to deprive someone of money or possessions","dt":"İnsanları kandırarak paralarını alan kişi","e1":"A notorious swindler.","e1t":"Namlı bir dolandırıcı.","e2":"Swindle (verb/noun).","e2t":"Dolandırmak / Üçkağıt."},{"w":"synonymous","tr":"eş anlamlı / (bir şeyle) özdeşleşmiş","te":"Adjective","tt":"Sıfat","de":"(Of a word or phrase) having the same meaning as another; or closely associated","dt":"Anlamı aynı olan; veya bir kavramla tamamen bütünleşmiş","e1":"\"Huge\" is synonymous with \"enormous\".","e1t":"\"Kocaman\" ile \"devasa\" eş anlamlıdır.","e2":"His name is synonymous with quality.","e2t":"Onun adı kalite ile özdeşleşmiştir."},{"w":"synopsis","tr":"özet / genel bakış","te":"Noun","tt":"İsim","de":"A brief summary or general survey of something","dt":"Bir konunun, kitabın veya filmin kısa özeti","e1":"To write a synopsis of the movie.","e1t":"Filmin özetini yazmak.","e2":"A brief synopsis of the report.","e2t":"Raporun kısa bir özeti."},{"w":"tabernacle","tr":"tapınak / mukaddes sandık / çadır","te":"Noun","tt":"İsim","de":"A fixed or movable dwelling, typically of light construction; or a meeting place for worship","dt":"Musevilerin çölde kullandıkları taşınabilir kutsal çadır; veya bazı Hristiyan grupların ibadet yeri","e1":"The Tabernacle in the wilderness.","e1t":"Çöldeki Kutsal Çadır.","e2":"Mormon Tabernacle.","e2t":"Mormon Tapınağı."},{"w":"tantalize","tr":"umutlandırıp boşa çıkarmak / canını çektirmek","te":"Verb","tt":"Fiil","de":"Torment or tease (someone) with the sight or promise of something that is unobtainable","dt":"Birine bir şeyi gösterip ama ona ulaşmasına izin vermeyerek acı çektirmek","e1":"The smell of food tantalized the hungry man.","e1t":"Yemek kokusu aç adamın iştahını kabarttı (canını çektirdi).","e2":"Tantalizing (adjective).","e2t":"Can yakıcı derecede çekici / İştah kabartan."},{"w":"tarantula","tr":"tarantula / iri örümcek","te":"Noun","tt":"İsim","de":"A large hairy spider found in tropical and subtropical America","dt":"Sıcak bölgelerde yaşayan, iri ve tüylü bir örümcek türü","e1":"The bite of a tarantula is painful but rarely fatal.","e1t":"Tarantula ısırığı acı vericidir ama nadiren öldürüldür.","e2":"","e2t":""},{"w":"tardy","tr":"geç kalan / yavaş / gecikmiş","te":"Adjective","tt":"Sıfat","de":"Delaying or delayed beyond the right or expected time; late","dt":"Beklenen zamanda gelmeyen; veya hareketlerinde çok yavaş olan","e1":"Tardy progress.","e1t":"Yavaş ilerleme.","e2":"He was punished for his tardy arrival.","e2t":"Geç kaldığı için cezalandırıldı."},{"w":"tarot","tr":"tarot / fal kartı","te":"Noun","tt":"İsim","de":"Playing cards, traditionally used for fortune","dt":"telling","e1":"Üzerinde çeşitli semboller bulunan ve fal bakmak için kullanılan kart destesi","e1t":"To read the tarot cards.","e2":"Tarot falı bakmak.","e2t":"A tarot reader."},{"w":"tarry","tr":"oyalanmak / beklemek / ziftli","te":"Verb/Adjective","tt":"Stay longer than intended; delay leaving; or covered with tar","de":"Bir yerde gereğinden fazla kalmak veya yola çıkmayı geciktirmek; veya zift kaplı","dt":"Why do you tarry here?","e1":"Neden burada oyalanıyorsun?","e1t":"Tarry ropes.","e2":"Katranlı (ziftli) halatlar.","e2t":""},{"w":"tautology","tr":"totoloji / gereksiz kelime tekrarı","te":"Noun","tt":"İsim","de":"The saying of the same thing twice in different words, generally considered to be a fault of style","dt":"Aynı anlamdaki kelimelerin bir arada kullanılmasıyla yapılan anlatım bozukluğu","e1":"\"A free gift\" is a tautology.","e1t":"\"Bedava hediye\" bir totolojidir (zaten hediye bedavadır).","e2":"Tautological (adjective).","e2t":"Gereksiz tekrar içeren."},{"w":"taxonomist","tr":"taksonom / sınıflandırma uzmanı","te":"Noun","tt":"İsim","de":"A biologist who groups organisms into categories","dt":"Canlıları bilimsel kurallara göre sınıflandıran uzman","e1":"The taxonomist identified the new species.","e1t":"Taksonom yeni türü tanımladı.","e2":"Taxonomy (noun).","e2t":"Sınıflandırma bilimi."},{"w":"temporal","tr":"dünyevi / geçici / zamana ait / şakakla ilgili","te":"Adjective","tt":"Sıfat","de":"Relating to worldly as opposed to spiritual affairs; secular; or relating to time","dt":"Manevi olmayan (dünyevi); veya zamanla ilgili; veya şakak kemiğine ait","e1":"Temporal power.","e1t":"Dünyevi güç (siyasi otorite).","e2":"Temporal lobe (anatomy).","e2t":"Şakak lobu."},{"w":"temporize / temporise","tr":"zaman kazanmaya çalışmak / nabza göre şerbet vermek","te":"Verb","tt":"Fiil","de":"Avoid making a decision or committing oneself in order to gain time","dt":"Karar vermeyi geciktirerek vakit kazanmaya çalışmak; veya duruma göre davranmak","e1":"He was temporizing, hoping for a better offer.","e1t":"Daha iyi bir teklif bekleyerek zaman kazanmaya çalışıyordu.","e2":"","e2t":""},{"w":"tendentious","tr":"taraflı / belli bir amaca hizmet eden","te":"Adjective","tt":"Sıfat","de":"Expressing or intending to promote a particular cause or point of view, especially a controversial one","dt":"Objektif olmayan, belirli bir fikri yaymaya çalışan (ön yargılı)","e1":"A tendentious report.","e1t":"Taraflı (belli bir görüşü empoze eden) bir rapor.","e2":"Tendentious arguments.","e2t":"Yanlı ve maksatlı argümanlar."},{"w":"tenebrous","tr":"karanlık / kasvetli / loş","te":"Adjective","tt":"Sıfat","de":"Dark; shadowy or obscure","dt":"Çok karanlık ve gölgeli; gizemli","e1":"The tenebrous depths of the cave.","e1t":"Mağaranın zifiri karanlık derinlikleri.","e2":"A tenebrous past.","e2t":"Karanlık (gizemli) bir geçmiş."},{"w":"tergiversation","tr":"lafı dolandırma / döneklik / kaçamak yapma","te":"Noun","tt":"İsim","de":"Evasion of straightforward action or utterance; or desertion of a cause","dt":"Bir karar vermemek için konuyu saptırma; veya taraf değiştirme","e1":"Political tergiversations.","e1t":"Siyasi döneklikler (veya kaçamaklar).","e2":"Tergiversate (verb).","e2t":"Lafı dolandırmak / Saf değiştirmek."},{"w":"termagant","tr":"dırdırcı ve hırçın kadın / şirret","te":"Noun","tt":"İsim","de":"A harsh","dt":"tempered or overbearing woman","e1":"Sürekli kavga çıkaran, huysuz ve baskın kadın","e1t":"His wife was a real termagant.","e2":"Karısı tam bir şirret (hırçın) kadındı.","e2t":""},{"w":"testament","tr":"vasiyetname / kanıt / ahit","te":"Noun","tt":"İsim","de":"A person's will, especially the part relating to personal property; or something that serves as a sign or evidence of a specified fact","dt":"Kişinin vasiyeti; veya bir durumun gücünü gösteren kesin kanıt","e1":"Last will and testament.","e1t":"Son arzu ve vasiyetname.","e2":"The success of the project is a testament to her hard work.","e2t":"Projenin başarısı, onun sıkı çalışmasının bir kanıtıdır."},{"w":"testator","tr":"vasiyetçi / vasiyet eden kimse","te":"Noun","tt":"İsim","de":"A person who has made a will or given a legacy","dt":"Öldükten sonra malvarlığının nasıl dağıtılacağını belirleyen (vasiyet bırakan) kişi","e1":"The wishes of the testator must be respected.","e1t":"Vasiyetçinin isteklerine saygı duyulmalıdır.","e2":"Testatrix (noun","e2t":"female)."},{"w":"throes","tr":"can çekişme / (bir şeyin) sancısı / şiddetli acı","te":"Noun","tt":"İsim (Plural)","de":"Intense or violent pain and struggle, especially accompanying birth, death, or great change","dt":"Doğum, ölüm veya büyük bir değişim sırasında çekilen şiddetli sarsıntı/acı","e1":"In the throes of death.","e1t":"Can çekişme halinde.","e2":"The country is in the throes of a revolution.","e2t":"Ülke bir devrimin sancıları (karışıklığı) içinde."},{"w":"timidity","tr":"ürkeklik / çekingenlik / mahcubiyet","te":"Noun","tt":"İsim","de":"Lack of self","dt":"confidence or courage","e1":"Kendine güven eksikliği, korkaklık","e1t":"To overcome one's timidity.","e2":"Çekingenliğini yenmek.","e2t":"Timid (adjective)."},{"w":"tincture","tr":"tentür / hafif iz / renk / (bir şeyden) etkilenmek","te":"Noun/Verb","tt":"İsim/Fiil","de":"A medicine made by dissolving a drug in alcohol; or a slight trace of something","dt":"Alkolde eritilmiş ilaç; veya (mecazi) bir şeyin hafif izi/belirtisi","e1":"Tincture of iodine.","e1t":"Tentürdiyot.","e2":"A tincture of sadness in his voice.","e2t":"Sesinde hafif bir üzüntü tınısı."},{"w":"tinsel","tr":"sim / pullu süs / (mecazi) sahte gösteriş","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A form of decoration consisting of thin strips of shiny metal foil; or something showy but cheap","dt":"Genellikle Noel ağacı süsü olan parıltılı şerit; veya ucuz ve geçici gösteriş","e1":"The tree was covered in tinsel.","e1t":"Ağaç simlerle kaplıydı.","e2":"The tinsel world of Hollywood.","e2t":"Hollywood'un o parıltılı ama sahte dünyası."},{"w":"toga","tr":"toga / antik Roma harmanisi","te":"Noun","tt":"İsim","de":"A loose flowing outer garment worn by the citizens of ancient Rome","dt":"Antik Roma vatandaşlarının giydiği geniş, dökümlü giysi","e1":"To wear a white toga.","e1t":"Beyaz bir toga giymek.","e2":"","e2t":""},{"w":"torpid","tr":"uyuşuk / hareketsiz / uyku halindeki","te":"Adjective","tt":"Sıfat","de":"Mentally or physically inactive; lethargic","dt":"Enerjisi olmayan, uyuşmuş ve tepkisiz","e1":"He became torpid after the big meal.","e1t":"Ağır yemekten sonra uyuşup kaldı.","e2":"The animal was in a torpid state during winter.","e2t":"Hayvan kış boyunca uyuşuk (kış uykusu benzeri) bir haldeydi."},{"w":"torque","tr":"tork / dönme momenti / burulma","te":"Noun","tt":"İsim","de":"A twisting force that tends to cause rotation","dt":"Bir nesneyi döndürmeye çalışan kuvvet (dönme momenti)","e1":"The engine produces high torque at low speeds.","e1t":"Motor düşük hızlarda yüksek tork üretiyor.","e2":"Tighten the bolts to the correct torque.","e2t":"Civataları doğru torkla (kuvvetle) sıkın."},{"w":"totter","tr":"sendeleyerek yürümek / sarsılmak / yıkılacak gibi olmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Move in a feeble or unsteady way","dt":"Düşecekmiş gibi dengesiz adımlarla yürümek; veya (sistem/bina için) sarsılmak","e1":"The drunk man tottered down the street.","e1t":"Sarhoş adam sokakta sendeleyerek ilerledi.","e2":"The government is tottering on the brink of collapse.","e2t":"Hükümet çöküşün eşiğinde sarsılıyor."},{"w":"touchy","tr":"alıngan / hassas / barut gibi","te":"Adjective","tt":"Sıfat","de":"(Of a person) easily upset or offended; oversensitive","dt":"En ufak şeye kırılan veya öfkelenen","e1":"Don't be so touchy!","e1t":"Bu kadar alıngan olma!","e2":"A touchy subject.","e2t":"Hassas (dikkatli konuşulması gereken) bir konu."},{"w":"tractable","tr":"uysal / söz dinleyen / kolay işlenen","te":"Adjective","tt":"Sıfat","de":"(Of a person or animal) easy to control or influence; or (of a situation/problem) easy to deal with","dt":"Kolayca yönetilebilen, yumuşak başlı; veya kolay çözülen","e1":"A tractable child.","e1t":"Söz dinleyen (uysal) bir çocuk.","e2":"Problems that are not easily tractable.","e2t":"Kolayca halledilemeyen sorunlar."},{"w":"traduce","tr":"iftira atmak / lekelemek / kötülemek","te":"Verb","tt":"Fiil","de":"Speak badly of or tell lies about (someone) so as to damage their reputation","dt":"Birinin adını lekelemek için hakkında yalan yanlış konuşmak","e1":"To traduce a person's character.","e1t":"Birinin karakterine kara çalmak.","e2":"","e2t":""},{"w":"transcend","tr":"aşmak / ötesine geçmek / üstün gelmek","te":"Verb","tt":"Fiil","de":"Be or go beyond the range or limits of","dt":"Normal sınırların veya deneyimin ötesine geçmek","e1":"Love transcends all boundaries.","e1t":"Aşk tüm sınırları aşar.","e2":"A greatness that transcends time.","e2t":"Zamanı aşan bir yücelik."},{"w":"transcendental","tr":"deneysel olmayan / soyut / doğaüstü","te":"Adjective","tt":"Sıfat","de":"Relating to a spiritual or nonphysical realm","dt":"Deney ve gözlem sınırlarını aşan, metafiziksel","e1":"Transcendental meditation.","e1t":"Transandantal (derin) meditasyon.","e2":"Transcendental philosophy.","e2t":"Deneyüstü felsefe."},{"w":"transgression","tr":"kural ihlali / günah / sınırı aşma","te":"Noun","tt":"İsim","de":"An act that goes against a law, rule, or code of conduct; an offense","dt":"Bir yasayı veya ahlaki kuralı çiğneme eylemi","e1":"A minor transgression of the rules.","e1t":"Kuralların ufak bir ihlali.","e2":"To forgive someone's transgressions.","e2t":"Birinin günahlarını (hatalarını) affetmek."},{"w":"transitory","tr":"geçici / fani / süreksiz","te":"Adjective","tt":"Sıfat","de":"Not permanent","dt":"Çok kısa süren, kalıcı olmayan (genellikle hayatın veya duyguların geçiciliği için)","e1":"The transitory nature of life.","e1t":"Hayatın geçici (fani) doğası.","e2":"Transitory success.","e2t":"Kalıcı olmayan başarı."},{"w":"transmute","tr":"dönüştürmek / şekil değiştirmek","te":"Verb","tt":"Fiil","de":"Change in form, nature, or substance","dt":"Bir maddeyi veya durumu tamamen başka bir şeye dönüştürmek","e1":"Alchemists tried to transmute lead into gold.","e1t":"Simyacılar kurşunu altına dönüştürmeye çalıştılar.","e2":"To transmute fear into confidence.","e2t":"Korkuyu özgüvene dönüştürmek."},{"w":"transpire","tr":"sızmak / (gizli bir şeyin) ortaya çıkması / (bitki) su buharlaştırmak","te":"Verb","tt":"Fiil","de":"(Of a secret or a fact) become known; be revealed; or (of a plant) give off water vapor","dt":"Gizli kalmış bir olayın sonradan öğrenilmesi; veya bitkilerin terlemesi","e1":"It later transpired that he had lied.","e1t":"Daha sonra onun yalan söylediği ortaya çıktı (anlaşıldı).","e2":"Plants transpire more in hot weather.","e2t":"Bitkiler sıcak havada daha fazla su buharlaştırır (terler)."},{"w":"trappings","tr":"aksesuar / süs püs / (mevkinin) gerekleri","te":"Noun","tt":"İsim (Plural)","de":"The outward signs, features, or objects associated with a particular situation, role, or thing","dt":"Bir makamın veya durumun beraberinde getirdiği tüm dışsal göstergeler ve süsler","e1":"All the trappings of wealth.","e1t":"Zenginliğin tüm şatafatı (aksesuarları).","e2":"The trappings of power.","e2t":"Gücün beraberinde getirdiği (törensel) ayrıcalıklar."},{"w":"travail","tr":"çile / ağır iş / doğum sancısı","te":"Noun/Verb","tt":"İsim/Fiil","de":"Painful or laborious effort","dt":"Çok yorucu, acı verici ve zorlu çalışma (uğraş)","e1":"Years of academic travail.","e1t":"Yıllarca süren akademik çile (uğraş).","e2":"To travail in the fields.","e2t":"Tarlalarda ağır işlerde çalışmak."},{"w":"travesty","tr":"gülünç taklit / parodi / rezalet","te":"Noun/Verb","tt":"İsim/Fiil","de":"A false, absurd, or distorted representation of something","dt":"Bir şeyin aslından saptırılmış, berbat ve gülünç halini yansıtan taklit","e1":"A travesty of justice.","e1t":"Adaletin rezaleti (adaletle dalga geçilmesi).","e2":"The trial was a travesty.","e2t":"Dava tam bir fiyaskoydu."},{"w":"treatise","tr":"risale / bilimsel inceleme / inceleme yazısı","te":"Noun","tt":"İsim","de":"A written work dealing formally and systematically with a subject","dt":"Belirli bir konuyu sistemli ve kapsamlı bir şekilde ele alan akademik eser","e1":"A treatise on philosophy.","e1t":"Felsefe üzerine bir bilimsel inceleme (risale).","e2":"He wrote a definitive treatise on the subject.","e2t":"Konuyla ilgili kesin (referans) bir eser kaleme aldı."},{"w":"tremulous","tr":"titrek / ürkek / heyecanlı","te":"Adjective","tt":"Sıfat","de":"Shaking or quivering slightly; or timid; nervous","dt":"Hafifçe titreyen (ses veya el); veya korkudan dolayı çekingen","e1":"A tremulous smile.","e1t":"Titrek (mahcup) bir gülümseme.","e2":"In a tremulous voice.","e2t":"Titrek bir ses tonuyla."},{"w":"trenchant","tr":"keskin / etkili / iğneleyici","te":"Adjective","tt":"Sıfat","de":"Vigorous or incisive in expression or style","dt":"Çok net, sert ve etkileyici (eleştiri veya yazı tarzı)","e1":"Trenchant criticism.","e1t":"Keskin (yerinde) eleştiri.","e2":"A trenchant analysis.","e2t":"Derinlikli ve etkili bir analiz."},{"w":"trepidation","tr":"endişe / heyecanla karışık korku / ürperti","te":"Noun","tt":"İsim","de":"A feeling of fear or agitation about something that may happen","dt":"Gelecekteki bir olay hakkında duyulan büyük huzursuzluk ve korku","e1":"With some trepidation, I opened the letter.","e1t":"Büyük bir endişeyle (ürpertiyle) mektubu açtım.","e2":"Full of trepidation.","e2t":"Endişe dolu."},{"w":"tribulation","tr":"çile / büyük sıkıntı / dert","te":"Noun","tt":"İsim","de":"A cause of great trouble or suffering","dt":"İnsanın sabrını zorlayan büyük dert veya üzüntü","e1":"The trials and tribulations of life.","e1t":"Hayatın zorlukları ve çileleri.","e2":"To face great tribulation.","e2t":"Büyük bir sıkıntıyla (imtihanla) karşılaşmak."},{"w":"tribunal","tr":"mahkeme / yargı kurulu / heyet","te":"Noun","tt":"İsim","de":"A court of justice or a seat or organ of justice","dt":"Özel bir konuyu karara bağlamak için kurulan mahkeme veya kurul","e1":"A war crimes tribunal.","e1t":"Savaş suçları mahkemesi.","e2":"An industrial tribunal.","e2t":"İş mahkemesi (heyeti)."},{"w":"trilogy","tr":"üçleme / triloji","te":"Noun","tt":"İsim","de":"A group of three related novels, plays, movies, etc.","dt":"Birbirini takip eden üç eserden oluşan dizi","e1":"The Lord of the Rings trilogy.","e1t":"Yüzüklerin Efendisi üçlemesi.","e2":"To complete a trilogy.","e2t":"Bir üçlemeyi tamamlamak."},{"w":"trinket","tr":"ıvır zıvır takı / ucuz süs eşyası","te":"Noun","tt":"İsim","de":"A small ornament or item of jewelry that is of little value","dt":"Maddi değeri düşük ama hoş görünen süs eşyası","e1":"A box full of trinkets.","e1t":"Ucuz takılarla dolu bir kutu.","e2":"(Bkz: Bauble).","e2t":""},{"w":"trite","tr":"basma kalıp / klişe / bayat","te":"Adjective","tt":"Sıfat","de":"(Of a remark, opinion, or idea) overused and consequently of little import; lacking originality or freshness","dt":"Çok sık kullanıldığı için orijinalliğini yitirmiş, sıkıcı ve klişe","e1":"A trite remark.","e1t":"Bayat (herkesin söylediği) bir söz.","e2":"The plot of the movie was a bit trite.","e2t":"Filmin konusu biraz klişeydi."},{"w":"trivia","tr":"ufak tefek bilgiler / önemsiz detaylar","te":"Noun","tt":"İsim (Plural)","de":"Details, considerations, or pieces of information of little importance or value","dt":"Genel kültür sorularında çıkan ama aslında önemsiz olan bilgiler","e1":"A trivia quiz.","e1t":"Genel kültür (detay bilgi) yarışması.","e2":"Trivial (adjective).","e2t":"Önemsiz / Basit."},{"w":"troth","tr":"sadakat / yemin / nişan","te":"Noun","tt":"İsim","de":"Faith or loyalty when pledged in a solemn agreement or undertaking","dt":"Birine verilen söz veya sadakat yemini","e1":"To plight one's troth.","e1t":"Sadakat yemini etmek / Nişanlanmak.","e2":"(Eski ve edebi bir kullanım).","e2t":""},{"w":"truculence","tr":"hırçınlık / kavgacılık / saldırganlık","te":"Noun","tt":"İsim","de":"Eagerness or quickness to argue or fight; aggressiveness","dt":"Kavga etmeye çok meraklı olma durumu; hırçınlık","e1":"The truculence of his behavior.","e1t":"Davranışındaki saldırganlık (kavgacılık).","e2":"Truculent (adjective).","e2t":"Hırçın / Saldırgan."},{"w":"truism","tr":"bedihî gerçek / malumu ilam / bayat gerçek","te":"Noun","tt":"İsim","de":"A statement that is obviously true and says nothing new or interesting","dt":"Zaten doğru olduğu herkesçe bilinen ve yeni bir şey söylemeyen ifade","e1":"It is a truism that money doesn't buy happiness.","e1t":"Paranın mutluluğu satın almadığı herkesin bildiği (beylik) bir gerçektir.","e2":"","e2t":""},{"w":"truncate","tr":"ucunu kesmek / kısaltmak / (bilgisayarda) kırpmak","te":"Verb","tt":"Fiil","de":"Shorten (something) by cutting off the top or the end","dt":"Bir şeyin üstünü veya sonunu keserek daha kısa hale getirmek","e1":"The report was truncated to save space.","e1t":"Yer kazanmak için rapor kısaltıldı.","e2":"Truncated pyramid (kesik piramit).","e2t":""},{"w":"tryst","tr":"gizli buluşma (sevgililer için)","te":"Noun","tt":"İsim","de":"A private romantic rendezvous between lovers","dt":"Sevgililerin kimseye haber vermeden yaptıkları randevu","e1":"A secret tryst in the garden.","e1t":"Bahçede gizli bir buluşma.","e2":"(Bkz: Rendezvous).","e2t":""},{"w":"tumid","tr":"şişmiş / kabarmış / tumturaklı (söz)","te":"Adjective","tt":"Sıfat","de":"(Especially of a part of the body) swollen; or (of language) pompous or bombastic","dt":"(Vücut parçası için) ödem yapmış veya şişmiş; veya (dil için) aşırı süslü ve abartılı","e1":"Tumid tissues.","e1t":"Şişmiş dokular.","e2":"A tumid prose style.","e2t":"Ağdalı ve tumturaklı bir yazı tarzı."},{"w":"tumult","tr":"arbede / gürültülü kargaşa / ayaklanma / zihin karışıklığı","te":"Noun","tt":"İsim","de":"A loud, confused noise, especially one caused by a large mass of people; or a state of confusion or disorder","dt":"Büyük bir kalabalığın çıkardığı gürültülü karışıklık; veya içsel (zihinsel) karmaşa","e1":"The tumult of the crowd.","e1t":"Kalabalığın gürültü ve patırtısı.","e2":"Her mind was in a tumult.","e2t":"Zihni darmadağındı (karmaşa içindeydi)."},{"w":"tundra","tr":"tundra / donmuş düzlük","te":"Noun","tt":"İsim","de":"A vast, flat, treeless Arctic region of Europe, Asia, and North America in which the subsoil is permanently frozen","dt":"Kutup bölgelerinde yer alan, ağaçsız ve toprağı sürekli donmuş olan geniş düzlükler","e1":"The Siberian tundra.","e1t":"Sibirya tundrası.","e2":"","e2t":""},{"w":"turbid","tr":"bulanık / çamurlu / (mecazi) karışık","te":"Adjective","tt":"Sıfat","de":"(Of a liquid) cloudy, opaque, or thick with suspended matter; or confused or obscure in meaning or effect","dt":"(Sıvı için) tortulu ve bulanık; veya (zihin/anlatım için) net olmayan, karışık","e1":"Turbid river water.","e1t":"Nehrin bulanık suyu.","e2":"Turbid emotions.","e2t":"Karman çorman (net olmayan) duygular."},{"w":"turbulence","tr":"türbülans / çalkantı / kargaşa","te":"Noun","tt":"İsim","de":"Violent or unsteady movement of air or water, or of some other fluid; or a state of conflict or confusion","dt":"Hava veya sudaki şiddetli düzensiz hareket; veya (mecazi) çalkantılı dönem","e1":"The plane hit severe turbulence.","e1t":"Uçak şiddetli türbülansa girdi.","e2":"A period of political turbulence.","e2t":"Siyasi bir çalkantı (kargaşa) dönemi."},{"w":"turgid","tr":"şişkin / kabarık / tumturaklı (söz)","te":"Adjective","tt":"Sıfat","de":"Swollen and distended or congested; or (of language) tediously pompous or bombastic","dt":"(Vücut için) şişmiş; veya (mecazi) süslü ama içi boş, sıkıcı konuşma","e1":"Turgid veins.","e1t":"Şişkin damarlar.","e2":"A turgid writing style.","e2t":"Ağdalı ve tumturaklı bir yazı tarzı."},{"w":"turpitude","tr":"ahlaksızlık / rezalet / alçaklık","te":"Noun","tt":"İsim","de":"Depravity; wickedness","dt":"Utanç verici ahlaki düşüklük","e1":"Moral turpitude.","e1t":"Ahlaki çöküntü (yozlaşma).","e2":"Acts of moral turpitude.","e2t":"Alçakça eylemler."},{"w":"tutelage","tr":"himaye / koruma / gözetim / öğretmenlik","te":"Noun","tt":"İsim","de":"Protection of or authority over someone or something; guardianship; or instruction; tuition","dt":"Birinin koruması veya otoritesi altında olma; veya bir öğretmenden alınan özel ders","e1":"Under the tutelage of a master.","e1t":"Bir ustanın gözetiminde (eğitiminde).","e2":"Tutelary (adjective).","e2t":"Koruyucu."},{"w":"tyro","tr":"acemi / çömez / çaylak","te":"Noun","tt":"İsim","de":"A beginner or novice","dt":"Bir işte henüz çok yeni olan tecrübesiz kimse","e1":"A tyro in the field of science.","e1t":"Bilim dünyasında bir acemi.","e2":"(Bkz: Novice / Neophyte).","e2t":""},{"w":"ubiquitous","tr":"her yerde bulunan / yaygın","te":"Adjective","tt":"Sıfat","de":"Present, appearing, or found everywhere","dt":"Aynı anda her yerde karşımıza çıkan, çok yaygın","e1":"Smartphones are now ubiquitous.","e1t":"Akıllı telefonlar artık her yerde (yaygın).","e2":"The ubiquitous influence of mass media.","e2t":"Kitle iletişim araçlarının her yanı sarmış olan etkisi."},{"w":"ulterior","tr":"gizli / arkada yatan / asıl (niyet)","te":"Adjective","tt":"Sıfat","de":"Existing beyond what is obvious or admitted; intentionally hidden","dt":"Görünenden farklı olan, kasten gizlenen (niyet/sebep)","e1":"An ulterior motive.","e1t":"Art niyet (gizli amaç).","e2":"Without any ulterior reason.","e2t":"Herhangi bir gizli sebep olmaksızın."},{"w":"ultimatum","tr":"ultimatom / kesin uyarı","te":"Noun","tt":"İsim","de":"A final demand or statement of terms, the rejection of which will result in retaliation or a breakdown in relations","dt":"Reddedilmesi halinde sert sonuçlar doğuracak olan son ihtar","e1":"To issue an ultimatum.","e1t":"Ultimatom vermek.","e2":"The country ignored the ultimatum.","e2t":"Ülke ultimatomu dikkate almadı."},{"w":"umbrage","tr":"gücenme / kırılma / gölge","te":"Noun","tt":"İsim","de":"Offence or annoyance; or (archaic) shade or shadow","dt":"(Genellikle 'take umbrage' kalıbıyla) bir söze veya eyleme alınmak, gücenmek","e1":"She took umbrage at his remarks.","e1t":"Onun yorumlarına güvendi (içerledi).","e2":"To give umbrage (gücendirmek).","e2t":""},{"w":"unabated","tr":"hızı kesilmeden / aynı şiddette / dinmeyen","te":"Adjective","tt":"Sıfat","de":"Without any reduction in intensity or strength","dt":"Gücü veya şiddeti azalmadan devam eden","e1":"The storm continued unabated throughout the night.","e1t":"Fırtına gece boyunca hızı kesilmeden devam etti.","e2":"Her enthusiasm remained unabated.","e2t":"Coşkusu hiç azalmadan sürdü."},{"w":"unadulterated","tr":"saf / karışık olmayan / katıksız","te":"Adjective","tt":"Sıfat","de":"Not mixed or diluted with any different or extra elements; complete and absolute","dt":"İçine başka hiçbir şey karıştırılmamalı (saf); veya (mecazi) tam ve gerçek","e1":"Unadulterated joy.","e1t":"Katıksız (saf) neşe.","e2":"Unadulterated milk.","e2t":"Hilesiz (saf) süt."},{"w":"unalloyed","tr":"saf / halis / (duygu) gölgesiz","te":"Adjective","tt":"Sıfat","de":"(Chiefly of emotions) complete and unreserved; or (of metal) not alloyed","dt":"(Genellikle duygular için) içine başka bir his karışmamış, tertemiz; veya alaşımsız metal","e1":"Unalloyed happiness.","e1t":"Saf (lekesiz) mutluluk.","e2":"Unalloyed gold.","e2t":"Saf altın."},{"w":"unassailable","tr":"sarsılmaz / tartışılamaz / eleştirilemez","te":"Adjective","tt":"Sıfat","de":"Unable to be attacked, questioned, or defeated","dt":"Saldırıya veya eleştiriye kapalı olacak kadar güçlü ve kesin","e1":"An unassailable argument.","e1t":"Çürütülemez (kesin) bir argüman.","e2":"His position in the company is unassailable.","e2t":"Şirketteki konumu sarsılmazdır."},{"w":"unassuming","tr":"mütevazı / alçakgönüllü / gösterişsiz","te":"Adjective","tt":"Sıfat","de":"Not pretentious or arrogant; modest","dt":"Yeteneklerine veya başarısına rağmen öne çıkmaya çalışmayan","e1":"An unassuming young man.","e1t":"Alçakgönüllü (kendini öne çıkarmayan) genç bir adam.","e2":"He lived in an unassuming little house.","e2t":"Gösterişsiz küçük bir evde yaşıyordu."},{"w":"unbridled","tr":"dizginlenemez / sınırsız / başına buyruk","te":"Adjective","tt":"Sıfat","de":"Uncontrolled; unconstrained","dt":"Kontrol altına alınmamış, aşırı ve özgür (genellikle duygular için)","e1":"Unbridled ambition.","e1t":"Dizginlenemez hırs.","e2":"Unbridled joy.","e2t":"Sınırsız neşe."},{"w":"uncanny","tr":"tekinsiz / esrarengiz / doğaüstü gibi","te":"Adjective","tt":"Sıfat","de":"Strange or mysterious, especially in an unsettling way","dt":"İnsanı ürperten bir garipliği veya açıklanamaz bir benzerliği olan","e1":"An uncanny resemblance.","e1t":"Esrarengiz (şaşırtıcı) bir benzerlik.","e2":"He has an uncanny ability to predict the future.","e2t":"Geleceği tahmin etme konusunda doğaüstü bir yeteneği var."},{"w":"unconscionable","tr":"vicdansız / insafsız / aşırı","te":"Adjective","tt":"Sıfat","de":"Not right or reasonable; or unreasonably excessive","dt":"Vicdana veya mantığa sığmayan; çok aşırı ve haksız","e1":"Unconscionable behavior.","e1t":"Vicdansızca davranış.","e2":"To make an unconscionable profit.","e2t":"İnsafsızca (fahiş) kar elde etmek."},{"w":"unctuous","tr":"yağcı / yapmacık / (madde) yağlı","te":"Adjective","tt":"Sıfat","de":"(Of a person) excessively or ingratiatingly flattering; oily","dt":"İnanılmayacak kadar nazik ve samimiyetsiz davranan (yağcı)","e1":"An unctuous salesman.","e1t":"Yağcı (yaltakçı) bir satıcı.","e2":"Unctuous manners.","e2t":"Yapmacık ve yılışık tavırlar."},{"w":"unequivocal","tr":"açık ve net / şüphe götürmez / kesin","te":"Adjective","tt":"Sıfat","de":"Leaving no doubt; unambiguous","dt":"Başka yöne çekilemeyecek kadar net, kesin","e1":"An unequivocal rejection.","e1t":"Kesin (net) bir red.","e2":"His message was unequivocal.","e2t":"Mesajı şüpheye yer bırakmayacak kadar açıktı."},{"w":"unfaltering","tr":"sarsılmaz / tereddütsüz / kararlı","te":"Adjective","tt":"Sıfat","de":"Not faltering; steady; resolute","dt":"Hiç duraksamayan, zayıflık göstermeyen ve kararlı","e1":"Unfaltering courage.","e1t":"Sarsılmaz cesaret.","e2":"To move with unfaltering steps.","e2t":"Emin (tereddütsüz) adımlarla ilerlemek."},{"w":"unfeigned","tr":"samimi / gerçek / içten","te":"Adjective","tt":"Sıfat","de":"Genuine; sincere","dt":"Yapmacık olmayan, gerçekten hissedilen","e1":"Unfeigned admiration.","e1t":"İçten (gerçek) hayranlık.","e2":"She showed unfeigned relief.","e2t":"Samimi bir rahatlama gösterdi."},{"w":"unfettered","tr":"serbest / kısıtlanmamış / özgür","te":"Adjective","tt":"Sıfat","de":"Not confined or restricted","dt":"Prangalarından kurtulmuş; hiçbir engele takılmayan","e1":"Unfettered access to information.","e1t":"Bilgiye sınırsız (kısıtlamasız) erişim.","e2":"Unfettered competition.","e2t":"Serbest rekabet."},{"w":"unfledged","tr":"tüyleri çıkmamış / toy / tecrübesiz","te":"Adjective","tt":"Sıfat","de":"(Of a bird) not yet having developed the feathers necessary for flying; or inexperienced","dt":"(Kuş için) henüz uçamayan; veya (mecazi) çok genç ve deneyimsiz","e1":"An unfledged politician.","e1t":"Çiçeği burnunda (tecrübesiz) bir siyasetçi.","e2":"Unfledged wings.","e2t":"Henüz tüylenmemiş kanatlar."},{"w":"ungainly","tr":"hantal / sakar / biçimsiz","te":"Adjective","tt":"Sıfat","de":"(Of a person or movement) awkward; clumsy","dt":"Hareketleri zarif olmayan, kaba ve sakar","e1":"An ungainly teenager.","e1t":"Eli ayağı birbirine dolanan (sakar) bir genç.","e2":"He walked with an ungainly gait.","e2t":"Hantal (biçimsiz) bir yürüyüşü vardı."},{"w":"unilateral","tr":"tek taraflı","te":"Adjective","tt":"Sıfat","de":"(Of an action or decision) performed by or affecting only one person, group, or country involved in a particular situation, without the agreement of another or the others","dt":"Diğer tarafların rızasını almadan, sadece bir tarafça yapılan","e1":"A unilateral decision.","e1t":"Tek taraflı karar.","e2":"Unilateral disarmament.","e2t":"Tek taraflı silahsızlanma."},{"w":"unimpeachable","tr":"hatasız / kusursuz / güvenilir","te":"Adjective","tt":"Sıfat","de":"Entirely trustworthy and impossible to doubt","dt":"Şüphe edilemeyecek kadar dürüst ve sağlam (lekesiz)","e1":"A man of unimpeachable character.","e1t":"Karakteri tartışılmaz (kusursuz) bir adam.","e2":"Unimpeachable evidence.","e2t":"Çok güvenilir (sarsılmaz) kanıt."},{"w":"uninhibited","tr":"çekinmesiz / doğal / serbest","te":"Adjective","tt":"Sıfat","de":"Expressing one's feelings or thoughts unselfconsciously and without restraint","dt":"İçinden geldiği gibi davranan, utangaçlık veya çekince duymayan","e1":"Uninhibited laughter.","e1t":"Kahkahalarla, çekinmeden gülme.","e2":"She is very uninhibited on stage.","e2t":"Sahnede çok rahattır (kendini kısıtlamaz)."},{"w":"unkempt","tr":"bakımsız / dağınık / darmadağın (saç vb.)","te":"Adjective","tt":"Sıfat","de":"(Especially of a person) having an untidy or disheveled appearance","dt":"Taranmamış, özen gösterilmemiş ve kirli görünen","e1":"Unkempt hair.","e1t":"Darmadağın (bakımsız) saç.","e2":"He looked unkempt and tired.","e2t":"Bakımsız ve yorgun görünüyordu."},{"w":"unmitigated","tr":"tam / düpedüz / hafifletilmemiş (olumsuz)","te":"Adjective","tt":"Sıfat","de":"Absolute; unqualified, typically of something bad","dt":"(Genellikle kötü bir durum için) tam, kesin ve hiçbir istisnası olmayan","e1":"An unmitigated disaster.","e1t":"Tam bir felaket (hezimet).","e2":"Unmitigated gall.","e2t":"Düpedüz küstahlık."},{"w":"unobtrusive","tr":"göze batmayan / mütevazı / çekinik","te":"Adjective","tt":"Sıfat","de":"Not conspicuous or attracting attention","dt":"Dikkat çekmeye çalışmayan, sessizce işini yapan","e1":"An unobtrusive waiter.","e1t":"Göze batmadan servis yapan garson.","e2":"The service was efficient and unobtrusive.","e2t":"Hizmet verimli ve rahatsızlık vermeyecek (mütevazı) düzeydeydi."},{"w":"unpalatable","tr":"tatsız / kabul edilemez / nahoş","te":"Adjective","tt":"Sıfat","de":"(Of food or drink) difficult to eat or swallow; or (of an idea/fact) difficult to accept","dt":"(Yemek için) lezzetsiz; veya (gerçek/fikir için) kabullenilmesi güç, acı","e1":"Unpalatable food.","e1t":"Yenmeyecek kadar kötü yemek.","e2":"The unpalatable truth.","e2t":"Acı (nahoş) gerçek."},{"w":"unpretentious","tr":"gösterişsiz / sade / mütevazı","te":"Adjective","tt":"Sıfat","de":"Not attempting to impress others with an appearance of greater importance, talent, or culture than is actually possessed","dt":"Olduğundan farklı görünmeye çalışmayan, doğal ve basit","e1":"An unpretentious hotel.","e1t":"Lüks olmayan, sade bir otel.","e2":"He is a very unpretentious person.","e2t":"Çok mütevazı (sade) biridir."},{"w":"unprincipled","tr":"ilkesiz / ahlaksız / kuralsız","te":"Adjective","tt":"Sıfat","de":"(Of a person or their behavior) not acting in accordance with moral principles","dt":"Ahlaki değerleri olmayan, dürüst davranmayan","e1":"Unprincipled behavior.","e1t":"Ahlaksızca davranış.","e2":"An unprincipled rogue.","e2t":"İlkesiz (karanlık) bir düzenbaz."},{"w":"unquenchable","tr":"dindirilemez / sönmez / doyurulamaz","te":"Adjective","tt":"Sıfat","de":"(Of a feeling or desire) unable to be slaked or satisfied","dt":"Bitmek bilmeyen, tatmin edilemeyen (tutku vb.)","e1":"An unquenchable thirst for knowledge.","e1t":"Dinmek bilmeyen bir bilgi açlığı.","e2":"Unquenchable fire.","e2t":"Sönmeyen ateş."},{"w":"unrequited","tr":"karşılıksız (duygu)","te":"Adjective","tt":"Sıfat","de":"(Of a feeling, especially love) not returned or rewarded","dt":"(Genellikle aşk için) karşı taraftan cevap alamayan","e1":"Unrequited love.","e1t":"Karşılıksız aşk.","e2":"(Bkz: Requite","e2t":"karşılık vermek"},{"w":"unruly","tr":"zapt edilemez / haylaz / söz dinlemez","te":"Adjective","tt":"Sıfat","de":"Disorderly and disruptive and not amenable to discipline or control","dt":"Disipline girmeyen, taşkınlık yapan","e1":"Unruly children.","e1t":"Yaramaz (söz dinlemez) çocuklar.","e2":"Unruly hair.","e2t":"Şekil almayan (asi) saç."},{"w":"unseemly","tr":"yakışıksız / edebe aykırı","te":"Adjective","tt":"Sıfat","de":"(Of behavior or actions) not proper or appropriate","dt":"Duruma veya görgü kurallarına uymayan","e1":"Unseemly behavior for a teacher.","e1t":"Bir öğretmene yakışmayacak davranış.","e2":"An unseemly argument.","e2t":"Yakışıksız bir tartışma."},{"w":"unspeakable","tr":"tarif edilemez (kötü) / dille anlatılamaz","te":"Adjective","tt":"Sıfat","de":"Too bad or horrific to be expressed in words","dt":"Kelimelerin yetersiz kaldığı kadar iğrenç veya korkunç","e1":"Unspeakable cruelty.","e1t":"Tarif edilemez (dehşet verici) bir zulüm.","e2":"An unspeakable crime.","e2t":"Anlatılamayacak kadar kötü bir suç."},{"w":"unswerving","tr":"sarsılmaz / sapmayan / sadık","te":"Adjective","tt":"Sıfat","de":"Not changing or becoming weaker; steady","dt":"Yolundan veya inancından asla dönmeyen","e1":"Unswerving loyalty.","e1t":"Sarsılmaz sadakat.","e2":"Unswerving commitment to the cause.","e2t":"Davaya olan tavizsiz bağlılık."},{"w":"untenable","tr":"savunulamaz / dayanaksız","te":"Adjective","tt":"Sıfat","de":"(Especially of a theory or a position) not able to be maintained or defended against attack or objection","dt":"Eleştiriler karşısında tutunması imkansız olan (çürük)","e1":"An untenable position.","e1t":"Savunulamaz (geçersiz) bir konum/durum.","e2":"This theory is completely untenable.","e2t":"Bu teori tamamen dayanaksızdır."},{"w":"untoward","tr":"beklenmedik / ters / aksilik","te":"Adjective","tt":"Sıfat","de":"Unexpected and inappropriate or inconvenient","dt":"Planlanmamış ve işleri zorlaştıran, nahoş","e1":"Unless something untoward happens...","e1t":"Beklenmedik (ters) bir şey olmazsa...","e2":"Untoward circumstances.","e2t":"Olumsuz (ters) şartlar."},{"w":"unwitting","tr":"farkında olmayan / bilmeden yapılan","te":"Adjective","tt":"Sıfat","de":"(Of a person) not aware of the full facts; or (of an action) unintentional","dt":"Gerçeği bilmeyen; veya bir şeyi kasten yapmayan","e1":"An unwitting accomplice.","e1t":"(Olayın içinde olduğunu) bilmeyen suç ortağı.","e2":"An unwitting mistake.","e2t":"Farkında olmadan yapılan bir hata."},{"w":"upbraid","tr":"azarlamak / paylamak / sitem etmek","te":"Verb","tt":"Fiil","de":"Find fault with (someone); scold","dt":"Birini yaptığı bir hatadan dolayı şiddetle eleştirmek","e1":"He upbraided them for their laziness.","e1t":"Onları tembelliklerinden dolayı azarladı.","e2":"(Bkz: Rebuke / Scold).","e2t":""},{"w":"uproarious","tr":"gürültülü / kahkahalara boğan / neşeli","te":"Adjective","tt":"Sıfat","de":"Characterized by or provoking loud noise or uproar; or very funny","dt":"Çok gürültülü veya insanı çok güldüren","e1":"Uproarious laughter.","e1t":"Kahkahalarla dolu (gürültülü) gülüş.","e2":"An uproarious comedy.","e2t":"İnsanı gülmekten kırıp geçiren bir komedi."},{"w":"urbane","tr":"nazik / görgülü / şehirli","te":"Adjective","tt":"Sıfat","de":"(Of a person, especially a man) courteous, confident, and refined in manner","dt":"Çok kibar, kendinden emin ve görgü kurallarını bilen","e1":"An urbane gentleman.","e1t":"Görgülü (nazik) bir beyefendi.","e2":"Urbanity (noun).","e2t":"Kibarlık / Görgülülük."},{"w":"urchin","tr":"sokak çocuğu / afacan / kestane","te":"Noun","tt":"İsim","de":"A mischievous young child, especially one who is poorly or raggedly dressed","dt":"Genellikle fakir görünümlü ama yaramaz çocuk; veya deniz kestanesi","e1":"Sea urchin.","e1t":"Deniz kestanesi.","e2":"Street urchins.","e2t":"Sokak çocukları."},{"w":"ursine","tr":"ayı gibi / ayıya benzer","te":"Adjective","tt":"Sıfat","de":"Relating to or resembling bears","dt":"Ayılarla ilgili veya ayıyı andıran","e1":"An ursine appetite.","e1t":"Ayı gibi bir iştah.","e2":"His ursine strength.","e2t":"Ayıvari (muazzam) gücü."},{"w":"usurp","tr":"gasp etmek / zorla almak (taht/makam)","te":"Verb","tt":"Fiil","de":"Take (a position of power or importance) illegally or by force","dt":"Bir makamı veya gücü haksız yere, zorla ele geçirmek","e1":"To usurp the throne.","e1t":"Tahtı gasp etmek.","e2":"He attempted to usurp the principal's authority.","e2t":"Müdürün yetkisini gasp etmeye çalıştı."},{"w":"usury","tr":"tefecilik / aşırı faizcilik","te":"Noun","tt":"İsim","de":"The action or practice of lending money at unreasonably high rates of interest","dt":"Çok yüksek faizle para ödünç verme işi","e1":"To be charged with usury.","e1t":"Tefecilikle suçlanmak.","e2":"Usurer (noun).","e2t":"Tefeci."},{"w":"utopia","tr":"ütopya / hayali ideal ülke","te":"Noun","tt":"İsim","de":"An imagined place or state of things in which everything is perfect","dt":"Her şeyin kusursuz olduğu hayali, ideal toplum veya yer","e1":"A political utopia.","e1t":"Siyasi bir ütopya.","e2":"Utopian (adjective).","e2t":"Ütopik / Hayalperest."},{"w":"uxorious","tr":"karısına aşırı düşkün","te":"Adjective","tt":"Sıfat","de":"Having or showing a great or excessive fondness for one's wife","dt":"Karısına aşırı derecede bağlı ve onun her dediğini yapan (erkek)","e1":"He is an uxorious husband.","e1t":"Karısına aşırı düşkün (kılıbıkça bağlı) bir kocadır.","e2":"","e2t":""},{"w":"vacillate","tr":"tereddüt etmek / kararsız kalmak / bocalamak","te":"Verb","tt":"Fiil","de":"Alternate or waver between different opinions or actions; be indecisive","dt":"İki fikir veya durum arasında gidip gelmek, bir türlü karar verememek","e1":"He vacillated between the two choices.","e1t":"İki seçenek arasında bocaladı (kararsız kaldı).","e2":"Vacillation (noun).","e2t":"Kararsızlık."},{"w":"vacuous","tr":"boş / anlamsız / boş bakan","te":"Adjective","tt":"Sıfat","de":"Having or showing a lack of thought or intelligence; mindless","dt":"Zihinsel derinliği olmayan, boş ve ifadesiz","e1":"A vacuous smile.","e1t":"Boş (anlamsız) bir gülümseme.","e2":"Vacuous comments.","e2t":"İçi boş (sığ) yorumlar."},{"w":"vagabond","tr":"serseri / evsiz barksız / hayta","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person who wanders from place to place without a home or job","dt":"Belli bir işi ve evi olmayan, sürekli gezen kimse","e1":"To live the life of a vagabond.","e1t":"Serseri bir hayat yaşamak.","e2":"Vagabondage (noun).","e2t":"Serserilik."},{"w":"vagary","tr":"kapris / beklenmedik değişiklik / gariplik","te":"Noun","tt":"İsim","de":"An unexpected and inexplicable change in a situation or in someone's behavior","dt":"Durumdaki veya davranıştaki öngörülemeyen tuhaf değişiklik","e1":"The vagaries of the weather.","e1t":"Havanın azizliği (beklenmedik değişimleri).","e2":"The vagaries of the stock market.","e2t":"Borsanın sağı solu belli olmayan halleri."},{"w":"vagrant","tr":"evsiz barksız / serseri / gezgin","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A person without a settled home or regular work who wanders from place to place","dt":"Bir yerden bir yere dolaşan, işsiz güçsüz kimse","e1":"A vagrant sleeping on a bench.","e1t":"Bankta uyuyan bir evsiz.","e2":"Vagrancy (noun).","e2t":"Serserilik / Başıboşluk."},{"w":"valedictory","tr":"veda niteliğinde / veda konuşması","te":"Adjective/Noun","tt":"Sıfat/İsim","de":"Serving as a farewell","dt":"Veda amaçlı yapılan (konuşma vb.)","e1":"A valedictory speech.","e1t":"Veda nutku.","e2":"Valedictorian (noun).","e2t":"Dönem birincisi (genelde veda konuşmasını o yapar)."},{"w":"valiant","tr":"yiğit / cesur / kahramanca","te":"Adjective","tt":"Sıfat","de":"Possessing or showing courage or determination","dt":"Tehlike karşısında büyük cesaret gösteren","e1":"A valiant warrior.","e1t":"Yiğit bir savaşçı.","e2":"To make a valiant effort.","e2t":"Kahramanca bir çaba göstermek."},{"w":"vampire","tr":"vampir / (mecazi) sömürgen","te":"Noun","tt":"İsim","de":"A corpse supposed to leave its grave at night to drink the blood of the living; or a person who preys on others","dt":"Efsanevi kan emici yaratık; veya başkalarını sömüren tip","e1":"He is a financial vampire.","e1t":"O bir finans vampiridir (insanları sömürür).","e2":"Vampire bat.","e2t":"Vampir yarasa."},{"w":"vanguard","tr":"öncü / öncü birlik / ilerici grup","te":"Noun","tt":"İsim","de":"A group of people leading the way in new developments or ideas; or the foremost part of an advancing army","dt":"Yeni fikirlerde veya orduda en önde giden grup","e1":"The vanguard of the revolution.","e1t":"Devrimin öncü kolu.","e2":"In the vanguard of technology.","e2t":"Teknolojinin en ön saflarında."},{"w":"vantage","tr":"avantaj / uygun durum / bakış açısı","te":"Noun","tt":"İsim","de":"A place or position affording a good view of something","dt":"Bir şeyi izlemek için en uygun ve avantajlı konum","e1":"From my vantage point.","e1t":"Benim bulunduğum (bakış) noktasından.","e2":"Vantage ground.","e2t":"Avantajlı konum."},{"w":"vapid","tr":"yavan / sıkıcı / tatsız / cansız","te":"Adjective","tt":"Sıfat","de":"Offering nothing that is stimulating or challenging; bland","dt":"İçeriği boş, heyecan vermeyen ve sönük","e1":"A vapid conversation.","e1t":"Yavan (tatsız) bir konuşma.","e2":"Vapid lyrics.","e2t":"İçi boş (basit) şarkı sözleri."},{"w":"variegated","tr":"alacalı / farklı renkleri olan / çeşitli","te":"Adjective","tt":"Sıfat","de":"Exhibiting different colors, especially as irregular patches or streaks","dt":"Farklı renklerden oluşan lekeli veya çizgili yapı","e1":"Variegated leaves.","e1t":"Alacalı (rengarenk) yapraklar.","e2":"A variegated career.","e2t":"Çok yönlü ve çeşitli bir kariyer."},{"w":"vassal","tr":"vasal / kul / bağımlı devlet/kişi","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"A holder of land by feudal tenure on conditions of homage and allegiance","dt":"Orta Çağ'da bir senyöre bağlı olan kişi; veya başka bir devlete bağımlı ülke","e1":"A vassal state.","e1t":"Uydu (bağımlı) devlet.","e2":"To be a vassal of the king.","e2t":"Kralın bir vasalı olmak."},{"w":"vaunt","tr":"övünmek / ballandıra ballandıra anlatmak","te":"Verb/Noun","tt":"Fiil/İsim","de":"Boast about or praise (something), especially excessively","dt":"Bir şeyi (genellikle hak etmediği kadar) çok övmek","e1":"The much","e1t":"vaunted new system.","e2":"Yere göğe sığdırılamayan yeni sistem.","e2t":"To vaunt one's achievements."},{"w":"vehement","tr":"şiddetli / coşkulu / sert","te":"Adjective","tt":"Sıfat","de":"Showing strong feeling; forceful, passionate, or intense","dt":"Çok güçlü duygularla, sert ve ödün vermez bir şekilde ifade edilen","e1":"A vehement denial.","e1t":"Şiddetli bir yalanlama.","e2":"He was vehement in his opposition.","e2t":"Muhalefetinde çok sertti."},{"w":"venal","tr":"rüşvet yiyen / satılık / çıkar düşkünü","te":"Adjective","tt":"Sıfat","de":"Showing or motivated by susceptibility to bribery; corrupt","dt":"Para için her şeyi yapabilecek, ahlaken bozuk","e1":"A venal politician.","e1t":"Rüşvetçi (satılık) siyasetçi.","e2":"Venal motives.","e2t":"Çıkarcı niyetler."},{"w":"venial","tr":"bağışlanabilir / hafif (hata/günah)","te":"Adjective","tt":"Sıfat","de":"(Of a fault or offense) slight and pardonable","dt":"Hoş görülebilecek, çok ağır olmayan hata","e1":"A venial sin.","e1t":"Küçük (bağışlanabilir) günah.","e2":"(Not: Mortal sin","e2t":"büyük günah"},{"w":"ventriloquist","tr":"vantrilok / karnından konuşan","te":"Noun","tt":"İsim","de":"A person who can speak or utter sounds so that they seem to come from somewhere else, typically a dummy","dt":"Dudaklarını kıpırdatmadan konuşabilen ve sesi bir kukladan geliyormuş gibi yapan sanatçı","e1":"The ventriloquist and his dummy.","e1t":"Vantrilok ve kuklası.","e2":"Ventriloquism (noun).","e2t":"Vantrilokluk."},{"w":"veracious","tr":"dürüst / doğrucu / gerçekçi","te":"Adjective","tt":"Sıfat","de":"Speaking or representing the truth","dt":"Her zaman doğruyu söyleyen veya gerçeği yansıtan","e1":"A veracious witness.","e1t":"Doğrucu bir tanık.","e2":"A veracious account of the events.","e2t":"Olayların gerçeğe uygun anlatımı."},{"w":"veranda / verandah","tr":"veranda / taraça / balkon","te":"Noun","tt":"Isim","de":"A roofed platform along the outside of a house, level with the ground floor","dt":"Evin girişinde veya yan tarafındaki üstü kapalı geniş balkon veya sundurma","e1":"We sat on the veranda and watched the sunset.","e1t":"Verandada oturup gün batımını izledik.","e2":"","e2t":""},{"w":"verbatim","tr":"kelimesi kelimesine / aynen","te":"Adverb/Adjective","tt":"In exactly the same words as were used originally","de":"Söylenenleri hiç değiştirmeden, olduğu gibi","dt":"To quote someone verbatim.","e1":"Birinden kelimesi kelimesine alıntı yapmak.","e1t":"A verbatim report.","e2":"Aynen (tutanak gibi) tutulmuş rapor.","e2t":""},{"w":"verbiage","tr":"laf kalabalığı / gereksiz söz uzatma","te":"Noun","tt":"İsim","de":"Excessively lengthy or technical speech or writing","dt":"Anlamı gölgeleyen lüzumsuz kelime yığını","e1":"To cut through the verbiage.","e1t":"Laf kalabalığını ayıklamak.","e2":"Technical verbiage.","e2t":"Teknik terimlerle dolu (anlaşılması güç) konuşma."},{"w":"verbose","tr":"çok konuşan / lafı uzatan","te":"Adjective","tt":"Sıfat","de":"Using or expressed in more words than are needed","dt":"Gereğinden fazla kelime kullanan, uzun ve sıkıcı","e1":"A verbose speaker.","e1t":"Lafı çok uzatan (geveze) konuşmacı.","e2":"Verbose style.","e2t":"Ağdalı (kelime kalabalığı olan) üslup."},{"w":"verdant","tr":"yemyeşil / taze (bitki)","te":"Adjective","tt":"Sıfat","de":"(Of countryside) green with grass or other rich vegetation","dt":"Otlarla ve bitkilerle kaplı, canlı yeşil renkte","e1":"Verdant valleys.","e1t":"Yemyeşil vadiler.","e2":"The verdant landscape of Ireland.","e2t":"İrlanda'nın yeşil manzarası."},{"w":"verisimilitude","tr":"gerçekçilik / gerçeğe benzerlik","te":"Noun","tt":"Isim","de":"The appearance of being true or real","dt":"Bir eserin veya anlatımın gerçeğe çok yakın olma (inandırıcılık) niteliği","e1":"The novel has a great sense of verisimilitude.","e1t":"Romanın muazzam bir gerçekçilik duygusu var.","e2":"","e2t":""},{"w":"verity","tr":"gerçeklik / temel gerçek","te":"Noun","tt":"İsim","de":"A true principle or belief, especially one of fundamental importance; or truth","dt":"Sarsılmaz ve temel doğruluk (genellikle çoğul kullanılır)","e1":"Eternal verities.","e1t":"Ebedi gerçekler.","e2":"To question the verity of his statement.","e2t":"İfadesinin doğruluğunu sorgulamak."},{"w":"vernacular","tr":"halk dili / yerel dil / anadil","te":"Noun/Adjective","tt":"İsim/Sıfat","de":"The language or dialect spoken by the ordinary people in a particular country or region","dt":"Bir bölgede halkın konuştuğu doğal dil (edebiyat dilinden farklı olarak)","e1":"To write in the vernacular.","e1t":"Halk diliyle yazmak.","e2":"Vernacular architecture.","e2t":"Yerel (geleneksel) mimari."},{"w":"vernal","tr":"bahara ait / ilkbahar","te":"Adjective","tt":"Sıfat","de":"Of, in, or appropriate to spring","dt":"İlkbaharla ilgili veya ilkbaharda olan","e1":"Vernal equinox.","e1t":"Bahar ekinoksu (gece","e2":"gündüz eşitliği).","e2t":"Vernal flowers."},{"w":"vertex","tr":"tepe noktası / zirve / (geometri) köşe","te":"Noun","tt":"İsim","de":"The highest point of something; or the point where two lines meet to form an angle","dt":"Bir şeyin en üst noktası; veya bir açının/şeklin köşesi","e1":"The vertex of a pyramid.","e1t":"Bir piramidin tepe noktası.","e2":"The vertex of an angle.","e2t":"Bir açının köşesi."},{"w":"vertigo","tr":"baş dönmesi / yükseklik korkusu kaynaklı baş dönmesi","te":"Noun","tt":"İsim","de":"A sensation of whirling and loss of balance, associated particularly with looking down from a great height","dt":"Özellikle yüksekten bakınca hissedilen denge kaybı ve dönme hissi","e1":"To suffer from vertigo.","e1t":"Baş dönmesinden muzdarip olmak.","e2":"Vertiginous (adjective).","e2t":"Baş döndürücü (yükseklik)."},{"w":"verve","tr":"coşku / heyecan / şevk","te":"Noun","tt":"Isim","de":"Vigor and spirit or enthusiasm","dt":"Özellikle sanat veya performansta gösterilen büyük enerji ve canlılık","e1":"To play the piano with great verve.","e1t":"Piyanoyu büyük bir şevkle (coşkuyla) çalmak.","e2":"His writing lacks verve.","e2t":"Yazısında heyecan/canlılık yok."},{"w":"vestige","tr":"iz / kalıntı / belirti","te":"Noun","tt":"İsim","de":"A trace of something that is disappearing or no longer exists","dt":"Yok olmuş veya kaybolmaya yüz tutmuş bir şeyin geriye kalan küçük izi","e1":"Vestiges of an ancient city.","e1t":"Antik bir şehrin kalıntıları.","e2":"Without a vestige of truth.","e2t":"İçinde zerre kadar (iz bile) gerçek olmadan."},{"w":"vicarious","tr":"başkasının deneyimiyle hissedilen / dolaylı","te":"Adjective","tt":"Sıfat","de":"Experienced in the imagination through the feelings or actions of another person","dt":"Bir şeyi bizzat yapmayıp başkasını izleyerek veya okuyarak o duyguyu yaşama","e1":"Vicarious pleasure.","e1t":"Başkasının mutluluğundan alınan (dolaylı) zevk.","e2":"To live vicariously through one's children.","e2t":"Kendi yaşayamadıklarını çocukları üzerinden yaşamak."},{"w":"vicissitude","tr":"hayatın iniş çıkışları / değişim","te":"Noun","tt":"İsim","de":"A change of circumstances or fortune, typically one that is unwelcome or unpleasant","dt":"(Genellikle çoğul) hayatın getirdiği beklenmedik iyi veya kötü değişimler","e1":"The vicissitudes of life.","e1t":"Hayatın cilveleri (iniş çıkışları).","e2":"To survive the vicissitudes of the market.","e2t":"Piyasanın değişkenliğine (zorluklarına) dayanmak."},{"w":"vie","tr":"yarışmak / çekişmek / rekabet etmek","te":"Verb","tt":"Fiil","de":"Compete eagerly with someone in order to do or achieve something","dt":"Bir şeyi elde etmek için başkalarıyla kıyasıya mücadele etmek","e1":"Athletes vying for the gold medal.","e1t":"Altın madalya için yarışan sporcular.","e2":"To vie for attention.","e2t":"Dikkat çekmek için çekişmek."},{"w":"vituperation","tr":"küfür / ağır dille kınama","te":"Noun","tt":"İsim","de":"Bitter and abusive language","dt":"Acı ve aşağılayıcı dil","e1":"He was unprepared for the vituperation that followed.","e1t":"Ardından gelen ağır hakaretlere (kınamaya) hazırlıksızdı.","e2":"Severe vituperation.","e2t":"Sert aşağılama."}];
